window.AACR_DATA = [{"drug_name": "AZD4241", "company": "AstraZeneca", "org_type": "公司", "target": "ER", "modality": "PROTAC", "importance_level": "高", "total_score": 90.5, "institution_score": 90, "track_score": 85, "milestone_score": 75, "field_heat_score": 90, "bonus_score": 5, "brief_reason": "AZD4241为AstraZeneca开发的口服ER PROTAC降解剂，靶向ERα实现高效降解以克服内分泌耐药。机构顶级、PROTAC赛道+ER+乳腺癌领域热度高，前临床建模支持2026年临床剂量选择，综合重要性高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1933", "id": "k57M_5wBZznHJdnt_W3O", "source_drug_name": "AZD4241", "title": "Preclinical mechanistic PK/PD/Efficacy modeling for AZD4241, a novel oral estrogen receptor (ER) degrader (PROTAC), to support dose selection during early clinical development", "abstract_text": "The high prevalence of ER‑positive breast cancer and the emergence of resistance to current endocrine therapies highlight the need for more effective ER degraders. AZD4241 is a novel, potent, orally bioavailable, and selective ER proteolysis‑targeting chimera (PROTAC) scheduled to enter clinical evaluation in 2026. We describe preclinical pharmacokinetic/pharmacodynamic (PK/PD) and efficacy modeling that quantifies the relationships among drug exposure, ERα degradation, and antitumor activity, thereby defining the extent of compound plasma exposure and target modulation required to achieve efficacy. These translational analyses are intended to inform dose selection and guide early clinical development of AZD4241.We developed a mechanistic mathematical model to quantify the exposure-target-response profile of AZD4241 in in-vivo patient‑derived xenograft (PDX) models harboring either wild-type or mutated ESR1. The PK module characterized plasma concentrations across a range of doses. An indirect‑response PK/PD module incorporated AZD4241 mechanism of action, whereby the compound accelerates ERα degradation yielding reductions in total ER protein measured by Western blot. The integrated PK/PD/Efficacy model linked plasma exposure, ERα levels, and tumor growth kinetics in the PDX models. Model parameters were estimated via nonlinear mixed‑effects (NLME) modeling using individual longitudinal PK, PD biomarker, and tumor volume data aggregated across multiple studies. The mathematical model captured the dose-dependent reduction of ERα and the associated inhibition of tumor growth observed in the PDX models. The level of ER degradation required to induce tumor regressions on the PDX models was also quantified and will be presented. This work provides quantitative, mechanistic insight into how exposure drives biomarker modulation and antitumor responses, delineating the level of ERα degradation required for robust efficacy in endocrine‑sensitive PDX models. The framework supports interpretation of compound‑induced PD effects in patients under defined dosing regimens and supplies translational evidence to enable dose selection in early clinical development.", "source_company": "AstraZeneca", "source_org_type": "公司", "row_number": 271, "target_meta": "ER", "MOA_meta": "PROTAC"}, {"drug_name": "LY4336619", "company": "Eli Lilly and Company", "org_type": "公司", "target": "ALPPL2×CD3", "modality": "bispecific antibody", "importance_level": "高", "total_score": 88.3, "institution_score": 95, "track_score": 92, "milestone_score": 75, "field_heat_score": 88, "bonus_score": 3, "brief_reason": "LY4336619为Eli Lilly开发的ALPPL2×CD3双抗，靶向实体瘤中高表达、低正常组织表达的ALPPL2，具备T细胞重定向杀伤活性。机构顶级、双抗赛道热门、显示良好体内外活性及可开发性、IND预计2026年，综合潜力突出。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4283", "id": "slXM_5wBX1NQZOEH-LG6", "source_drug_name": "LY4336619", "title": "Preclinical characterization of LY4336619, a novel ALPPL2xCD3 bispecific antibody, for the treatment of ovarian and endometrial cancer", "abstract_text": "Development of CD3-bispecific antibodies has been challenging in solid tumors due to the difficulty identifying tumor antigens with high tumoral expression but with minimal or no expression in normal tissues. Placental-like alkaline phosphatase 2 (ALPPL2) is overexpressed in various solid tumors, including ovarian and endometrial carcinomas, while its expression in normal tissues is largely restricted to the placenta. This expression profile makes ALPPL2 a promising target for CD3-bispecific antibody therapies. We have developed a fully human common light chain-based ALPPL2×CD3 bispecific antibody, LY4336619, on an Fc-silenced IgG1 backbone designed to engage ALPPL2 on tumor cells and CD3 on T cells, facilitating targeted T cell-mediated cytotoxicity against ALPPL2-expressing tumor cells. LY4336619 was generated by pairing a novel anti-ALPPL2 monoclonal antibody, identified through a murine immunization strategy, with an anti-CD3 antibody. The binding, target selectivity, and cytotoxic activity of LY4336619 were evaluated using multiple ALPPL2-expressing cell lines. In vivo efficacy was evaluated using immunocompromised murine models engrafted with human tumor xenografts and human peripheral blood mononuclear cells (PBMCs). Additionally, a comprehensive proteomics analysis was performed to characterize ALPPL2 expression across tumor tissue specimens. LY4336619 specifically bound to ALPPL2-expressing cell lines but spared ALPI and ALPL, the other more widely expressed alkaline phosphatase family members; it also bound to the highly homologous ALPP family member, a protein with similar limited normal expression and association with similar tumor types. LY4336619 engaged with both CD3 and ALPPL2, and induced concentration-dependent T-cell activation and T cell-mediated cytotoxicity in co-culture assays with T cells and ALPPL2-expressing tumor cells. Furthermore, it demonstrated antitumor activity and relatively low cytokine release as a single agent in human PBMC-engrafted mice with human tumor xenografts representing a range of ALPPL2 expression levels. Additional preliminary studies revealed that the combination treatment with LY4170156, a clinical-stage anti-FRα antibody-drug conjugate (ADC), resulted in more sustained and pronounced tumor growth inhibition compared to either monotherapy alone. Our ALPPL2×CD3 bispecific antibody exhibited IgG-like pharmacokinetics and low immunogenic potential. These findings demonstrate that LY4336619 has target specificity, favorable functional activity, and a promising developability profile. LY4336619 has the potential as a first-in-class medicine to treat ALPPL2-positive solid tumors, including ovarian and endometrial cancers. An IND submission is anticipated for 2026.", "source_company": "Eli Lilly and Company", "source_org_type": "公司", "row_number": 193, "target_meta": "ALPPL2,CD3", "MOA_meta": "双特异性抗体"}, {"drug_name": "PI3Ki/mTORi ADC", "company": "AbbVie Inc.", "org_type": "公司", "target": "PI3K/mTOR", "modality": "ADC", "importance_level": "高", "total_score": 88.3, "institution_score": 92, "track_score": 95, "milestone_score": 75, "field_heat_score": 90, "bonus_score": 4, "brief_reason": "新型pan-PI3K/mTOR双抑制剂作为首创ADC payload，靶向高度失调的PI3K/AKT/mTOR通路。AbbVie顶级MNC背景+ADC热门赛道+单剂显著肿瘤消退的强preclinical数据，综合潜力突出。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4414", "id": "eJ7M_5wBZznHJdnt_W3O", "source_drug_name": "PI3Ki/mTORi ADC", "title": "Discovery of novel pan-PI3K and mTOR dual inhibitors as first-in-class antibody-drug conjugate payloads", "abstract_text": "Despite the clinical success of microtubule inhibitor- and topoisomerase inhibitor-based ADCs, new classes of payloads with alternative mechanisms of action are needed to address clinical resistance and increase tumor responses. Constructing next-generation ADC payloads that target cancer-dependent pathways with a strong biological rationale for combination with other targeted agents, provides an opportunity to develop better-tolerated and more differentiated ADCs. The PI3K/AKT/mTOR signaling pathway is one of the most dysregulated in human cancers. Numerous small molecule efforts have targeted PI3K and mTOR, but these have achieved limited success. These agents are often associated with frequent dose interruptions and discontinuations due to undesirable on-target toxicities, as well as the emergence of drug resistance resulting from AKT reactivation.\nHere, we present novel pan-PI3K and mTOR dual inhibitors developed as first-in-class ADC payloads. We hypothesize that this novel payload strategy will achieve more robust and durable inhibition of the PI3K/AKT/mTOR pathway. Delivery via an ADC approach is expected to provide meaningful improvements in efficacy and tolerability compared to systemic small molecule treatments.\nExisting pan-PI3K and mTOR dual inhibitors often lack sufficient potency and present challenges for linker installation to enable an ADC approach. Guided by structure-based design, we have identified novel cores that significantly boost potency against various class I PI3K isoforms and mTOR enzymes, while maintaining excellent selectivity across a broad kinase panel. Additionally, we have explored multiple exit vectors to facilitate ADC linker installation, which is a critical component of ADC development.\nThe resulting PI3Ki/mTORi ADCs exhibited favorable drug-like properties and picomolar potency in cell-killing assays across a range of in vitro tumor models. Importantly, these ADCs also demonstrated a strong bystander effect, attributable to the highly efficient release of the cleavable linker within lysosomes and the permeable nature of the payloads being developed. These ADCs demonstrated significant in vivo efficacy by inducing tumor regressions across a variety of hematological and solid tumor models harboring PI3K genetic alterations, following administration of a single dose ranging from 3 to 10 mg/kg. Moreover, owing to their dual inhibitory activity against both PI3K and mTOR, our ADCs exhibited robust antitumor effects even in models with wild-type PI3K backgrounds, highlighting their broad therapeutic potential.\nTaken together, the PI3K/mTOR dual-inhibitor modality, combined with an ADC platform, offers an opportunity to target various cancer indications with dependencies on the PI3K/mTOR pathway, and provides opportunities for combination treatment regimens with other anticancer agents.", "source_company": "AbbVie Inc.\nAbbVie Bay Area", "source_org_type": "公司", "row_number": 1031, "target_meta": "PI3K,mTOR", "MOA_meta": "抗体偶联药物"}, {"drug_name": "AZD4241", "company": "AstraZeneca R&D", "org_type": "公司", "target": "ERα", "modality": "PROTAC", "importance_level": "高", "total_score": 88.3, "institution_score": 95, "track_score": 92, "milestone_score": 75, "field_heat_score": 90, "bonus_score": 4, "brief_reason": "AZD4241为口服ERα PROTAC，可高效降解野生型及突变型ERα，在HR+乳腺癌前临床模型中显示显著抗肿瘤活性，包括克服ESR1突变及CDK4/6抑制剂耐药。AstraZeneca作为头部MNC、PROTAC热门赛道+ERα在乳腺癌重要靶点、较强的PDX模型数据支撑较高综合重要性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1903", "id": "alXM_5wBX1NQZOEH-LO6", "source_drug_name": "AZD4241", "title": "AZD4241, an orally bioavailable ERα PROTAC, degrades wild-type and mutant ERα and delivers anti-tumour activity in preclinical breast cancer models", "abstract_text": "Estrogen receptor alpha (ERα) is a member of the nuclear hormone receptor superfamily and a key driver of hormone receptor-positive (HR+) breast cancer. Current ER‑pathway inhibitors include aromatase inhibitors (letrozole, anastrozole, exemestane), selective estrogen receptor modulators (SERMs; tamoxifen), and selective estrogen receptor degraders (SERDs; fulvestrant, elacestrant, imlunestrant). In metastatic ER‑positive disease, resistance is common and often involves the emergence of ESR1 mutations (e.g., Y537S, D538G). These mutations occur in the ligand‑binding domain of ERα and enable ligand‑independent ER activation, reducing the effectiveness of aromatase inhibitors and some antagonists. This underscores the need for novel treatments that target ER in both wild-type (ESR1wt) and mutant (ESR1m) settings, including more effective ERα degraders, as demonstrated clinically by SERDs. Here we characterise AZD4241, a novel ER‑targeting proteolysis targeting chimera (PROTAC), that degrades both wt and mutant ERα and delivers anti‑tumour efficacy in preclinical breast cancer models. AZD4241 degraded ERα in ESR1wt cell lines (IC50 0.4 nM in MCF7 cells) and showed good oral bioavailability across species. ERα half-life was reduced through PROTAC‑mediated degradation requiring cereblon engagement and proteasomal activity. In MCF7 cells engineered to express clinically relevant ESR1 mutations, AZD4241 reduced ERα with degradation potency (IC50 0.2-1.0 nM) comparable to ESR1wt controls. AZD4241 completely inhibited estradiol‑induced gene expression (e.g., GREB1, PGR, and TFF1) and suppressed proliferation of ER‑dependent breast cancer cell lines with low-nanomolar IC50 values. In vivo, AZD4241 induced dose‑dependent anti‑tumour activity and, in some cases, tumour regressions across ESR1wt and ESR1m patient‑derived xenograft (PDX) models, including a palbociclib‑resistant model. Efficacy was associated with marked reductions in ERα protein levels and decreased ER pathway activity, supporting a pharmacodynamic link between target degradation, suppression of ER signalling and efficacy. Collectively, these data confirm that AZD4241 is a potent, orally bioavailable degrader of wt and mutant ERα, driving anti-tumour efficacy in ESR1wt, ESR1m, and CDK4/6 inhibitor‑resistant PDX models. These findings support the use of AZD4241 as a novel ER-PROTAC with potential to overcome key resistance mechanisms to current standards of care and deliver clinical benefit for patients with ER‑positive breast cancer.", "source_company": "AstraZeneca R&D", "source_org_type": "公司", "row_number": 1262, "target_meta": "ESR1", "MOA_meta": "PROTAC"}, {"drug_name": "molecular glue degrader (MGD)", "company": "Triana Biomedicines", "org_type": "公司", "target": "CCNE1", "modality": "molecular glue degrader", "importance_level": "高", "total_score": 87.5, "institution_score": 85, "track_score": 95, "milestone_score": 80, "field_heat_score": 90, "bonus_score": 5, "brief_reason": "分子胶降解剂直接靶向此前不可成药的CCNE1蛋白，实现选择性降解，对CCNE1扩增实体瘤及CDK4/6i耐药乳腺癌显示强效抗肿瘤活性。Triana作为头部分子胶平台型biotech，获Pfizer等顶级投资且融资强劲，赛道热度极高且preclinical数据优秀。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8742", "id": "4J7M_5wBZznHJdnt_W3O", "source_drug_name": "molecular glue degrader (MGD)", "title": "Discovery of a selective molecular glue degrader of CCNE1 for the treatment of CCNE1-amplified solid tumors and CDK4/6i-resistant HR+/HER2- breast cancers", "abstract_text": "Cyclin E1 (CCNE1) is a central regulator of the G1 to S-phase transition of the cell cycle and a key dependency in multiple solid tumor types, including ovarian and endometrial cancers, and promotes resistance to CDK4/6 inhibitors in HR+/HER2- breast cancer. CCNE1 lacks a druggable pocket or enzymatic activity, which has precluded attempts to develop drugs that inhibit its function. Efforts to inhibit CCNE1 activity indirectly with CDK2 kinase inhibitors have been hindered by poor selectivity and dose-limiting toxicities that prevent full pathway suppression. Here we report the discovery of a molecular glue degrader (MGD) that co-opts the CRL4CRBN E3 ubiquitin ligase to eliminate the CCNE1 protein. Single-particle cryo-electron microscopy identifies a novel non-G-loop degron on CCNE1 that drives direct recognition of CCNE1 by the MGD:CRBN:DDB1 complex without preventing CDK2 binding to CCNE1. In cell lines analyzed, MGD treatment triggers rapid, CRBN-dependent depletion of CCNE1 with complete selectivity over the rest of the proteome. MGD-induced CCNE1 degradation exerts potent and selective anti-proliferative effects, with over 500-fold greater potency in CCNE1 amplified lines compared to non-amplified lines, a substantial improvement relative to CDK2 inhibitors (~15-fold potency window). In HR+/HER2- breast cancer cell lines with evolved resistance to the combination of a CDK4/6 inhibitor and fulvestrant, co-treatment with the MGD restores sensitivity. Oral administration of the MGD drives robust CCNE1 reduction and antitumor activity in a CCNE1-amplified xenograft model. These data suggest that directly and selectively degrading CCNE1 could provide an effective targeted therapy for CCNE1-amplified solid tumors and overcome resistance to CDK4/6 inhibitors in HR+/HER2- breast cancer.", "source_company": "Triana Biomedicines", "source_org_type": "公司", "row_number": 91, "target_meta": "CCNE1", "MOA_meta": "降解剂"}, {"drug_name": "BH-501242", "company": "BlossomHill Therapeutics, Inc.", "org_type": "公司", "target": "pan-KRAS", "modality": "inhibitor", "importance_level": "高", "total_score": 87.5, "institution_score": 85, "track_score": 95, "milestone_score": 80, "field_heat_score": 90, "bonus_score": 5, "brief_reason": "BH-501242为新型pan-KRAS on/off抑制剂，靶向switch II pocket，实现广谱KRAS突变亚型高活性抑制，机制新颖并兼顾on/off状态。机构为由知名科学家创立的美国临床阶段biotech，融资强劲，KRAS热门赛道+优秀体外/体内前药效+口服成药性支持高分。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6416", "id": "zp7M_5wBZznHJdnt_W3O", "source_drug_name": "BH-501242", "title": "Design and discovery of BH-501242, a novel pan-KRAS on/off inhibitor targeting KRAS switch II pocket", "abstract_text": "KRAS mutations are involved in approximately 25% of all tumors and are frequent oncogenic drivers in lung (32%), colorectal (40%), and pancreatic cancers (85-90%). The most common KRAS driver mutations are on codon 12 and 13, including G12C, G12D, G12V, G12R, G13A, G13D, etc. The G12C mutation has been effectively targeted using a covalent strategy that exploits the unique reactivity of the cysteine residue. Other mutations, however, require inhibitors with high intrinsic binding affinity with KRAS to be effective in clinic. MRTX1133 was the first to demonstrate low single-digit nM cell potency for G12D mutation; however, the inhibitor lacked the ADME properties required for a successful oral drug. Since then, multiple KRAS inhibitors targeting G12D, G12V, or pan-KRAS mutations have advanced into clinical trials. Leveraging our structure-based drug design expertise, we designed a novel chemical scaffold targeting KRAS switch II pocket and identified the pan-KRAS inhibitor, BH-501242 after lead optimization on potency, ADME/PK, and safety properties. BH-501242 demonstrated excellent potency and target engagement across a broad spectrum of KRAS mutations and achieved sub-nM to low single-digit nM IC50 values in cellular anti-proliferation assays and anti-phosphorylation assays against downstream kinase ERK. In a panel of 15 cell lines with KRAS G12D mutation, 10 cell lines with G12V, and 11 cell lines with G12C, BH-501242 showed superior anti-cell proliferation activity with median IC50s of 1.31 nM (0.40 nM for GP2D - 9.96 nM for SUIT-2), 3.55 nM (1.84 nM for SW620 - 19.7 nM for SW900), and 2.13 nM (0.68 nM for SW1463 - 5.79 nM for SW756) against KRAS G12D, G12V, and G12C mutant cells, respectively. BH-501242 also demonstrated outstanding cell potency against other KRAS mutations including G12S, G12F, G12A, G13D and K117N. Mechanistically, BH-501242 tightly binds with both active (GTP-bound or “on”) and inactive (GDP-bound or “off”) forms of mutant KRAS, effectively blocking its interaction with downstream effector c-RAF, and inhibiting the phosphorylation of ERK. Synergistic effects were observed in combination with EGFR antibody cetuximab in colony formation assays with KRAS mutant cells. PK profiling revealed oral bioavailability of BH-501242 in multiple species and dose dependent plasma exposures in mouse xenograft tumor models. BH-501242 demonstrated excellent anti-tumor activity in multiple CDX mouse models with various KRAS mutations, including GP2D and HPAC models with G12D mutation, H441 with G12V, and MiaPaca-2 with G12C, etc. In conclusion, the strong preclinical profile provides a strong rationale for the advancement of BH-501242 into further development.", "source_company": "BlossomHill Therapeutics, Inc.", "source_org_type": "公司", "row_number": 108, "target_meta": "KRAS", "MOA_meta": "抑制剂"}, {"drug_name": "GFH603", "company": "GenFleet Therapeutics", "org_type": "公司", "target": "KEAP1", "modality": "molecular glue-like allosteric activator", "importance_level": "高", "total_score": 87.5, "institution_score": 85, "track_score": 90, "milestone_score": 85, "field_heat_score": 90, "bonus_score": 5, "brief_reason": "GFH603为分子胶样KEAP1别构激活剂，促进KEAP1-CUL3复合物组装并诱导NRF2降解，针对NRF2激活肿瘤尤其是鳞癌模型显示单药强效和肿瘤消退。GenFleet为国内头部biotech，已有KRAS抑制剂上市/临床领先，分子胶机制+NRF2靶点在肿瘤耐药领域热度高，前临床数据强劲包括PDX模型肿瘤消退及协同潜力，故综合评分高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4344", "id": "OVXM_5wBX1NQZOEH-LS6", "source_drug_name": "GFH603", "title": "GFH603: A molecular glue-like allosteric activator of the KEAP1-CUL3 E3 ligase complex for targeting NRF2-activated tumors", "abstract_text": "Background:\nConstitutive activation of NRF2, driven by NFE2L2 gain-of-function or KEAP1 or CUL3 loss-of-function mutations, disrupts KEAP1-CUL3-mediated NRF2 degradation and contributes to resistance to chemotherapy, immunotherapy, and targeted therapies, including RAS inhibitors. This oncogenic pathway is frequently altered in squamous cell carcinomas — such as esophageal (ESCC) and lung squamous cell carcinoma (LUSC) — via NFE2L2 hotspot mutations in the DLG/ETGE motifs. In lung adenocarcinoma (LUAD), KEAP1 mutations are common and often co-occur with KRAS mutations. Although KEAP1/NFE2L2 mutations are relatively uncommon in pancreatic ductal adenocarcinoma, more than half of tumors exhibit pronounced nuclear NRF2 accumulation, likely driven by activation of the RAS pathway. Despite the clinical relevance of this pathway, no approved therapies directly target KEAP1/NRF2-mutant tumors.\nMethods:\nGFH603 was developed as a molecular glue-like allosteric activator of KEAP1 to restore KEAP1-CUL3 E3 ligase function. Its ability to promote KEAP1-CUL3 complex formation, induce NRF2 degradation, and suppress proliferation of NRF2-driven cancer cells was evaluated in vitro. In vivo anti-tumor efficacy was assessed using xenograft models. Combination studies with pan-RAS inhibitors were conducted in KRAS/KEAP1 co-mutant cell lines. ADMET profiling was performed to assess drug-like properties.\nResults:\nGFH603 enhanced KEAP1-CUL3 complex assembly and promoted NRF2 degradation. In vitro, it induced NRF2 degradation in NFE2L2 W24C-mutant KYSE70 cells ( IC₅₀ = 1.7 nM) and inhibited proliferation of NFE2L2-amplified HCC95 cells (IC₅₀ = 3.6 nM). In the HCC95 xenograft model, GFH603 (5 mg/kg once daily) achieved significant tumor growth inhibition (TGI = 114%) and robust NRF2 degradation in tumor tissues. In the LU6407 NFE2L2-mutant patient-derived xenograft model, GFH603 (10 mg/kg once daily) demonstrated strong tumor regression as a single agent, indicating its potential as an effective monotherapy. Furthermore, GFH603 demonstrated synergistic anti-proliferative activity when combined with pan-RAS inhibitors in KRAS/KEAP1 co-mutant cell lines. ADMET profiling revealed favorable characteristics, including high oral bioavailability, low hERG liability, and negative Ames test results.\nConclusions:\nGFH603 restores KEAP1-CUL3 E3 ligase activity through a molecular glue mechanism, enabling targeted degradation of NRF2 in KEAP1/NFE2L2-mutant tumors. It demonstrates potent efficacy as monotherapy in NRF2-activated squamous cancer models (e.g., ESCC, LUSC) and synergizes with pan-RAS inhibitors in KRAS/KEAP1 co-mutant cells. These findings support GFH603 as a promising therapeutic candidate for overcoming NRF2-driven resistance and addressing a critical unmet need in oncology. Further preclinical and clinical development are warranted.", "source_company": "GenFleet Therapeutics", "source_org_type": "公司", "row_number": 171, "target_meta": "Keap1", "MOA_meta": "激活剂"}, {"drug_name": "W308051", "company": "GlaxoSmithKline plc", "org_type": "公司", "target": "PSMA", "modality": "bispecific T cell engager", "importance_level": "高", "total_score": 87.5, "institution_score": 95, "track_score": 90, "milestone_score": 75, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "W308051为GSK从WuXi引进的PSMA×CD3双特异性T细胞衔接器，针对mCRPC，preclinical数据显示高PSMA亲和力、强肿瘤杀伤和较低细胞因子释放，安全性窗口优于竞品。机构为全球头部MNC、TCE+PSMA热门赛道、临床推进潜力强，故综合评分高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4500", "id": "S1XM_5wBX1NQZOEH-LS6", "source_drug_name": "W308051", "title": "The affinity-optimized bispecific T cell engager W308051 selectively kills PSMA-expressing tumor cells with limited cytokine secretion", "abstract_text": "Metastatic castration‐resistant prostate cancer (mCRPC) remains a therapeutic challenge with limited treatment options. Here, we report the preclinical characterization of W308051, a bispecific T cell engager developed by GSK under license from WuXi, designed to target prostate‐specific membrane antigen (PSMA) on malignant cells and CD3 on T lymphocytes. W308051 demonstrates a higher binding affinity to PSMA compared to the competitor molecules AMG160 and AMG340 with a KD of 16 pM as shown by surface plasmon resonance and also stronger binding in ELISA and cell-based binding assays. However, its affinity for CD3 with a KD of 60 nM is lower than AMG160 but higher than AMG340, a rationale design choice to increase the therapeutic index. In vitro studies reveal that W308051 induces potent cytotoxicity against PSMA‐positive cancer cells, achieving efficacies comparable to AMG160 and surpassing those of AMG340 across multiple cell lines with variable PSMA expression levels. Furthermore, in vivo experiments utilizing a cell line-derived xenograft model with the LNCaP cell line in immunodeficient mice engrafted with human peripheral blood mononuclear cells demonstrated complete tumor growth inhibition at higher dosing regimens, reflective of AMG160’s profile. Importantly, in vitro cytokine release associated with W308051 treatment was reduced relative to AMG160 and marginally elevated compared to AMG340, suggesting a potentially improved safety profile and an expanded therapeutic window. Pharmacokinetic analyses indicate that the use of T cell receptor domains for bispecific antibody assembly confers properties akin to those observed with conventional monoclonal antibodies. Collectively, these findings support the further clinical investigation of W308051 as a promising therapeutic modality for mCRPC.", "source_company": "GlaxoSmithKline plc", "source_org_type": "公司", "row_number": 253, "target_meta": "PSMA", "MOA_meta": "其他"}, {"drug_name": "topoisomerase I inhibitor-ADC", "company": "AbbVie Inc.", "org_type": "公司", "target": "未披露", "modality": "ADC", "importance_level": "高", "total_score": 87.5, "institution_score": 95, "track_score": 90, "milestone_score": 75, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "药物为TOP1i-ADC，通过抑制topoisomerase I诱导肿瘤细胞免疫原性细胞应激和衰老样状态，增强免疫原性并与anti-PD1协同。AbbVie作为头部MNC，TOP1i-ADC赛道热度高（类似Enhertu/Trodelvy临床成功），摘要展示强preclinical免疫机制洞察和协同潜力，得分较高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5726", "id": "C1XM_5wBX1NQZOEH-LK6", "source_drug_name": "topoisomerase I inhibitor-ADC", "title": "Induction of immunogenic cell stress through the inhibition of topoisomerase I", "abstract_text": "When normal tissue homeostasis cannot be maintained, cells initiate distinct pathways of regulated cell death (RCD) to preserve health of the organism. Exploiting RCD pathways to induce tumor cell death is a mainstay of cancer therapy. More recently it has become appreciated that the manner in which cancer cells die can have drastic impacts on local tissue microenvironments and ultimately disease progression. Emerging preclinical and clinical data suggest certain forms of RCD can cause the release of damage-associated molecular patterns (DAMPS) to not only activate innate immunity but also generate antigen-specific adaptive immune responses, a defining feature of immunogenic cell death (ICD). In addition to bona fide ICD, it is recognized that tumor cells paralyzed in a non-replicative senescent state are also highly immunogenic through the release of immunostimulatory soluble factors, upregulation of major histocompatibility complex (MHC) molecules, and altering the array of antigens presented to T cells.\nClinical data with topoisomerase I inhibitor (TOP1i)-ADCs show responses in numerous human cancers with growing evidence that immune system engagement may contribute to their clinical activity. Therefore, we sought to determine the immunogenicity of topoisomerase I inhibition. TOP1i treatment in vitro induced a highly immunogenic state of murine tumor cells, which when injected to mice, acted as a cellular vaccine and resulted in the rejection of secondary live tumors. Vaccination with TOP1i treated cells required host type 1 conventional dendritic cells (cDC1) and CD8+ T cells for protection. Interestingly, characterization of cell death kinetics following TOP1 inhibition reveled that the immunogenicity of TOP1i treated cells is largely derived from stressed, living cells rather than dead cells. Treatment with highly immunogenic doses of TOP1i in vitro revealed that tumor cells rapidly alter their physiology to exhibit multiple hallmarks of cellular senescence. Following TOP1i treatment, tumor cells were durably arrested in cell cycle (G2M), upregulated p21, exhibited heightened β-galactosidase activity and produced inflammatory senescence associated secretory phenotype (SASP) cytokines, as well as type I IFNs, and became sensitive to senolytic agents. Moreover, TOP1i treated cells were able to induce robust cDC1 activation and promote the acquisition of a mregDC like phenotype which was dependent on tumor expression of the stimulator of interferon genes (STING). Using a human antigen expressing syngeneic tumor model we demonstrated that TOP1i-ADC activity was greatly enhanced in the presence of adaptive immunity and synergizes with anti-PD1 therapy. Together these data highlight the immunogenic nature of topoisomerase I inhibition and provide new insights into the potential mechanism underlying the emerging clinical benefits of TOP1i-ADCs for the treatment of cancer.", "source_company": "AbbVie Inc.", "source_org_type": "公司", "row_number": 499, "target_meta": "not available", "MOA_meta": "抗体偶联药物"}, {"drug_name": "LUA006", "company": "Shanghai QiLu Pharmaceutical Research and Development Center LTD.", "org_type": "公司", "target": "EGFR/B7-H3", "modality": "bispecific ADC", "importance_level": "高", "total_score": 87.5, "institution_score": 85, "track_score": 95, "milestone_score": 80, "field_heat_score": 90, "bonus_score": 8, "brief_reason": "LUA006为双特异性EGFR/B7-H3 ADC，采用双payload设计以解决肿瘤异质性和耐药问题，靶点EGFR和B7-H3在实体瘤中常见共表达且正常组织少见。齐鲁制药作为国内TOP3药企，在热门ADC+双靶点+双payload赛道preclinical数据强劲，包括优异体内外疗效和耐药模型活性，综合潜力突出。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5446", "id": "ulXM_5wBX1NQZOEH-LS6", "source_drug_name": "LUA006", "title": "Preclinical development of LUA006: A bispecific EGFR/B7-H3 ADC with dual payloads to address tumor heterogeneity and resistance", "abstract_text": "Background: While antibody-drug conjugates (ADCs) have emerged as a transformative therapeutic class, their clinical utility is largely limited by either on-target, off-tumor toxicities or acquired drug resistance. EGFR and B7-H3 are clinically validated targets that are frequently co-expressed in a range of solid tumors including non-small cell lung cancer (NSCLC), especially lung squamous cell carcinoma (LUSC), esophageal squamous cell carcinoma (ESCC), and Head and neck squamous cell carcinoma (HNSCC), while exhibit rare co-expression in normal tissues. It has been revealed that both heterogeneous expression of a single target and acquired resistance to a single payload often compromise the efficacy of monospecific ADCs containing a single payload. To address these challenges, we generated LUA006, a bispecific ADC targeting both EGFR and B7-H3 with attenuated EGFR binding to reduce on-target, off-tumor toxicity and enhanced B7-H3 binding and internalization dynamics to improve anti-tumor efficacy, particularly in tumors with heterogeneous expression of a single target. Additionally, LUA006 incorporates two distinct payload classes, to achieve deep response and overcome payload-associated resistance.\nMethods: A bispecific anti-EGFR/B7-H3 IgG was site-specifically conjugated to two payloads with complimentary mechanism of actions and well optimized DAR values. Meanwhile, the linkers for each payload were screened to enable sequential payload release. LUA006 demonstrated high DAR homogeneity and stability in vitro.\nResults: LUA006 demonstrated superior internalization efficiency versus parental antibodies, indicating synergistic targeting. It achieved nanomolar-level cytotoxicity against diverse cancer cell lines with variable EGFR/B7-H3 expression, while showing minimal toxicity to normal human epidermal keratinocytes, resulting in a broader therapeutic window than clinical stage EGFR monospecific ADCs in vitro. In vivo, a single dose of LUA006 induced profound, durable tumor regression in cell-derived xenograft (CDX) models, surpassing combinations of mono-payload ADCs and monospecific ADCs. Critically, LUA006 maintained efficacy in CDX models with intrinsic low sensitivity to each payload used by LUA006 and in models overexpressing drug efflux pumps, demonstrating robust activity against diverse resistance mechanisms.\nConclusion: LUA006 is a novel bispecific ADC with dual payloads that may enhance efficacy in tumors with heterogeneous expression of a single target or with resistance toward either of dual payloads. Its potent efficacy, reduced toxicity profile and activity in resistant models support further development as a promising therapy for EGFR/B7-H3-expressing solid tumors.", "source_company": "Shanghai QiLu Pharmaceutical Research and Development Center LTD.", "source_org_type": "公司", "row_number": 1236, "target_meta": "EGFR,CD276", "MOA_meta": "抗体偶联药物"}, {"drug_name": "α TROP2/PDL1-TOP1i", "company": "Earendil Labs", "org_type": "公司", "target": "TROP2 & PDL1", "modality": "ADC", "importance_level": "高", "total_score": 86.5, "institution_score": 85, "track_score": 95, "milestone_score": 75, "field_heat_score": 90, "bonus_score": 5, "brief_reason": "药物为靶向TROP2和PDL1的双特异性ADC，搭载TOP1抑制剂payload，结合免疫检查点阻断与靶向细胞毒递送机制，在多个模型中显示肿瘤消退和良好安全性。Earendil Labs作为获巨额融资（近8亿美元）并与Sanofi合作的人工智能驱动头部biotech，赛道为热门双特异ADC+热门靶点，临床前强度强，支持进入临床开发。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9463", "id": "TVXM_5wBX1NQZOEH-LS6", "source_drug_name": "α TROP2/PDL1-TOP1i", "title": "A bispecific TROP2/PDL1 antibody-drug conjugate demonstrates enhanced antitumor activity and favorable safety profile", "abstract_text": "Purpose\nThis study aimed to develop and characterize a bispecific antibody-drug conjugate (ADC) targeting both TROP2 and PDL1, to address the limitations of current single-target therapies in advanced cancers.\nMethods\nWe engineered a humanized bispecific antibody (bsAb) against TROP2 and PDL1 (α TROP2/PDL1), and subsequently produced the bispecific ADC using an optimized hydrophilic linker and TOP1 inhibitor payload. Comprehensive in vitro characterization encompassed binding affinity, internalization efficiency, and PDL1 degradation assays. In vivo efficacy was assessed across multiple xenograft models, while safety assessment was conducted in transgenic mice and non-human primates.\nResults\nα TROP2/PDL1 demonstrated potent bispecific activity, featuring efficient cellular binding and rapid internalization. The bsAb induced significant PDL1 internalization and degradation, and showed marked tumor growth inhibition in MC-38-huTrop2/PDL1 model. The bsAb TOP1i conjugated ADC (α TROP2/PDL1-TOP1i) exhibited enhanced potency, characterized by robust cytotoxicity against multiple Trop2/PDL1-expressing cell lines, potent bystander killing effects, and tumor regression in multiple CDX models. Notably, the ADC showed excellent stability and tolerability in cynomolgus monkeys, with no significant adverse effects observed in safety studies.\nConclusion\nα TROP2/PDL1-TOP1i represents a promising therapeutic strategy for treatment-resistant cancers, effectively combining PD1/PDL1 immune checkpoint blockade with TROP2-targeted cytotoxic payload delivery while maintaining a favorable safety profile, supporting its advancement to clinical development.", "source_company": "Earendil Labs", "source_org_type": "公司", "row_number": 134, "target_meta": "TROP2,PDL1", "MOA_meta": "抗体偶联药物"}, {"drug_name": "trastuzumab-DXd ADC", "company": "WuXi XDC", "org_type": "公司", "target": "未披露", "modality": "ADC", "importance_level": "高", "total_score": 86.5, "institution_score": 85, "track_score": 95, "milestone_score": 75, "field_heat_score": 90, "bonus_score": 5, "brief_reason": "该ADC采用新型linker架构和payload优化，以trastuzumab为基础构建，展示改善稳定性、旁观者效应及宽治疗指数的preclinical数据。WuXi XDC作为全球领先的ADC CRDMO（市场份额超22%，连续获奖），在热门ADC赛道中创新平台价值高，preclinical强度强且具制造优势。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5416", "id": "TZ7M_5wBZznHJdnt_W3O", "source_drug_name": "trastuzumab-DXd ADC", "title": "Transforming ADC development with novel linker architectures and payload optimization", "abstract_text": "Antibody-drug conjugates (ADCs) are an expanding class of targeted cancer therapies, and innovations in linker and payload chemistry are critical to improving therapeutic index and clinical outcomes. We present four complementary strategies designed to enhance ADC performance and manufacturability. First, a novel linker adapter, N-(ortho-hydroxyphenyl)-N-methylcarbamate, enables controlled side-chain modification and rapid payload release, resulting in pronounced tumor regression in colonic cancer xenograft models. Second, a Val-Ala-based double self-immolative linker-payload platform was developed to optimize hydroxyl group-containing payload integration. A trastuzumab-DXd ADC constructed using this platform demonstrated improved stability, cathepsin B sensitivity, potent bystander effect, and a broad therapeutic index in HER2-positive and -negative xenografts, with favorable safety profiles in preclinical toxicology studies. Additionally, we introduce a streamlined two-step synthesis of a disaccharide linker for glycosite-specific conjugation, reducing the traditional >15-step process and enabling cost-effective production of homogeneous ADCs with enhanced quality and consistency. Finally, we report the first ADC incorporating homocamptothecin as a payload, achieving antitumor activity comparable to Enhertu at 3 mg/kg while demonstrating improved tolerability in NCI-N87 xenograft models. Collectively, these innovations establish a versatile platform for next-generation ADCs, combining precision targeting, improved pharmacological properties, and scalable manufacturing to advance clinical oncology.", "source_company": "WuXi XDC", "source_org_type": "公司", "row_number": 266, "target_meta": "not available", "MOA_meta": "抗体偶联药物"}, {"drug_name": "a novel kinesin degrader", "company": "Boundless Bio", "org_type": "公司", "target": "novel kinesin", "modality": "degrader", "importance_level": "高", "total_score": 86.5, "institution_score": 85, "track_score": 90, "milestone_score": 85, "field_heat_score": 90, "bonus_score": 5, "brief_reason": "靶向新型kinesin（癌症细胞ecDNA分离必需，正常细胞非必需），采用degrader modality实现选择性降解，机制新颖针对ecDNA+高危癌种。Boundless Bio为临床阶段NASDAQ上市公司，IND已获批并进入First-in-human试验（KOMODO-1），preclinical强度高且具first-in-class潜力。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11468", "id": "7lXM_5wBX1NQZOEH-LO6", "source_drug_name": "a novel kinesin degrader", "title": "Selective degradation of a novel kinesin as a potential therapeutic strategy addressing high-risk extrachromosomal DNA (ecDNA) positive cancers, including breast cancer", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Boundless Bio", "source_org_type": "公司", "row_number": 819, "target_meta": "kinesin", "MOA_meta": "降解剂"}, {"drug_name": "MYC Development Candidate (DC)", "company": "Dewpoint Therapeutics, Inc.", "org_type": "公司", "target": "MYC", "modality": "inhibitor", "importance_level": "高", "total_score": 86.5, "institution_score": 85, "track_score": 95, "milestone_score": 75, "field_heat_score": 90, "bonus_score": 8, "brief_reason": "口服小分子通过调控MYC转录凝聚体（condensate）抑制MYC活性，针对历史上极难成药的MYC靶点实现首创性直接调控。Dewpoint作为头部biotech专注condensate新模态，MYC赛道热度极高且具突破性，preclinical展示robust抗瘤活性及in vivo pathway modulation，支持高潜力开发。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3828", "id": "q1XM_5wBX1NQZOEH-LS6", "source_drug_name": "MYC Development Candidate (DC)", "title": "Oral small-molecule condensate modulator (c-mod) inhibits MYC activity and demonstrates robust anti-tumor activity across diverse tumor models", "abstract_text": "MYC is a key oncogenic driver that is commonly overexpressed or amplified across a wide spectrum of human cancers. Despite its therapeutic relevance, MYC has remained difficult to target pharmacologically due to its intrinsically disordered structure and dependence on dynamic biomolecular interactions. MYC forms transcriptional condensates to drive oncogene expression, suggesting that it might be inhibited by this mechanism. Using a condensate-focused screening approach, we previously identified first-generation MYC condensate modulators (c-mods) capable of disrupting MYC condensates and suppressing MYC-dependent transcription. Here we describe the profile of our orally bioavailable MYC Development Candidate (DC) with improved pharmacological properties, potency, and selectivity. This compound reduces MYC condensates, represses MYC-driven gene expression, and selectively inhibits the growth of MYC-addicted cancer cells by inducing apoptosis and cell-cycle arrest. Broad in vitro activity has been observed across multiple solid tumor types. In animal models, oral administration of our DC produces robust anti-tumor responses with an emerging tolerability profile supportive of continued development. Preclinical biomarker studies further demonstrate modulation of MYC pathway activity in vivo. Together, these findings position MYC condensate modulation as a promising therapeutic strategy for MYC-driven cancers.", "source_company": "Dewpoint Therapeutics, Inc.", "source_org_type": "公司", "row_number": 957, "target_meta": "MYC", "MOA_meta": "抑制剂"}, {"drug_name": "novel TEAD degraders", "company": "Amphista Therapeutics", "org_type": "公司", "target": "TEAD", "modality": "degrader", "importance_level": "高", "total_score": 86.5, "institution_score": 85, "track_score": 90, "milestone_score": 85, "field_heat_score": 90, "bonus_score": 5, "brief_reason": "靶向Hippo通路关键转录因子TEAD，通过新型FBXO22介导的Targeted Glue机制实现蛋白降解，在preclinical阶段展示优秀降解效率、口服生物利用度和体内活性。Amphista作为海外头部TPD biotech，赛道为热门分子胶/TPD新机制，里程碑包括首例FBXO22介导体内降解，综合潜力高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6451", "id": "fZ7M_5wBZznHJdnt_W7P", "source_drug_name": "novel TEAD degraders", "title": "Rational development of novel FBXO22-mediated TEAD Targeted Glues™ for mesothelioma and NSCLC treatment", "abstract_text": "TEAD transcription factors are critical effectors of the Hippo signalling pathway and represent promising therapeutic targets in cancers with pathway dysregulation. We report the rational discovery and optimization of a novel class of TEAD degraders that exploit a Targeted Glue™ mechanism to achieve FBXO22-dependent proteasomal degradation. Our novel degraders with differentiated chemical matter demonstrate exceptional degradation profiles (sub-nM DC50, >90% Dmax), coupled with outstanding on-pathway selectivity as measured by global proteomics vs >7000 other proteins measured. Through comprehensive mechanistic studies, we elucidated that our warheads engage FBXO22 via covalent modification of C326. This structural understanding, enabled by high-resolution ternary complex cryo-EM data, facilitated systematic structure-activity relationship optimization of both degradation potency and kinetic parameters. In vitro, our lead compounds exhibited deep (>150% GImax) and potent (nM GI50) anti-proliferative activity in mesothelioma, with synergistic efficacy observed in combination with EGFR inhibitors in EGFR-mutant NSCLC models. Critically, our optimized compounds achieved oral bioavailability and demonstrated robust in vivo activity, representing the first demonstration of FBXO22-mediated degradation in vivo. In mesothelioma xenograft models, we observed rapid (2h, first time point measured), deep (>95%) and sustained (≥72h) TEAD degradation leading to prolonged biomarker inhibition. Our work provides critical design principles for this degrader class and validates FBXO22-TEAD degradation as a therapeutically relevant approach for Hippo pathway-driven cancers, with promise in mesothelioma and combination strategies for EGFR-mutant NSCLC.", "source_company": "Amphista Therapeutics", "source_org_type": "公司", "row_number": 1208, "target_meta": "TEAD", "MOA_meta": "降解剂"}, {"drug_name": "Cpd-1308", "company": "Hengrui pharmaceuticals Co. Ltd.", "org_type": "公司", "target": "CDK4 and CDK2", "modality": "inhibitor", "importance_level": "高", "total_score": 86.5, "institution_score": 95, "track_score": 85, "milestone_score": 75, "field_heat_score": 90, "bonus_score": 5, "brief_reason": "Cpd-1308为小分子双靶点CDK4/CDK2抑制剂，针对HR+乳腺癌及CDK4/6抑制剂耐药机制，具有长驻留时间和更好选择性。Hengrui作为中国顶级创新药企（市场价值和创新排名领先），赛道热门（克服CDK4/6i耐药的细胞周期靶向），PDX模型显示显著疗效，preclinical强度高故综合评分高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1501", "id": "XVXM_5wBX1NQZOEH-LS6", "source_drug_name": "Cpd-1308", "title": "Dual-targeting CDK4 and CDK2 overcomes resistance to CDK4/6 inhibitors in HR+ breast cancer", "abstract_text": "Cyclin-dependent kinase 4/6 inhibitors (CDK4/6i)have proven clinical efficacy in hormone receptor-positive (HR+) breast cancer (BC) patients. However,current clinical challenges are frequent hematologic toxicities mediated by CDK6 inhibition and acquired drug resistance driven in part by cyclin E/CDK2 activation. The next generation of CDK inhibitors such as atirmociclib targeting CDK4 and tagtociclib targeting CDK2 have demonstrated encouraging early efficacy, and the combination of a selective CDK4 inhibitor and a selective CDK2 inhibitor has entered clinical trials. We propose that simultaneous targeting CDK4 and CDK2 with a small-molecule may provide a new therapeutic option.\nTo address the efficacy of dual-targeting CDK4 and CDK2, compound-1308 (Cpd-1308) were synthesized. In NanoBRET assay measuring cellular target engagement, Cpd-1308 had an IC50 against CDK4 of 24nM, an IC50 against CDK2 of 123nM, and an IC50 against CDK6 of 521nM, suggesting a CDK4/2 inhibitor over CDK6. Antiproliferative potency and inhibition of retinoblastoma (RB) phosphorylation were tested in multiple cancer cell lines. Human primary hematopoietic stem and precursor CD34+ cells (CD34+ HSPC) were used to estimate impact on the inhibition of hematopoietic cells proliferation. Cpd-1308 and palbociclib are nearly equipotent in MCF7 cells, whereas Cpd-1308 showed a 7-fold reduced impact on CD34+HSPC cells when compared to palbociclib. These results suggested that CDK4:CDK6 selectivity of Cpd-1308 was greater than that of palbociclib.\nFurther kinetic characterization using surface plasmon resonance (SPR) spectroscopy revealed that Cpd-1308 has long residence time on CDK2 in comparison with tagtociclib. Long residence time on CDK2 may potentially lead to improved efficacy against drug resistance driven in part by cyclin E/CDK2 activation. Cpd-1308 indeed showed superior potency on antiproliferation of derived palbociclib resistant MCF7 cells (MCF7-palbo-r) and derived abemaciclib resistant MCF7 cells (MCF7-abema-r). We tested the in vivo efficacy of Cpd-1308 in CDK4/6i-resistant HR+ breast cancer patient-derived xenografts tumors (PDX). Tumor growth was inhibited in a dose-dependent manner and significant growth inhibition was observed. Cpd-1308 demonstrated significant resistance-overcoming activity.\nTaken together, we demonstrate activity of Cpd-1308 in HR+ breast cancers and CDK4/6i-resistant breast cancers. Our research results indicate that co-targeting CDK4 and CDK2 with a small-molecule may grant new therapeutic opportunities for patients.", "source_company": "Hengrui pharmaceuticals Co. Ltd.", "source_org_type": "公司", "row_number": 1234, "target_meta": "CDK4,CDK2", "MOA_meta": "抑制剂"}, {"drug_name": "TOP1i-ADC", "company": "AbbVie Inc.", "org_type": "公司", "target": "TOP1", "modality": "ADC", "importance_level": "高", "total_score": 85.8, "institution_score": 92, "track_score": 95, "milestone_score": 65, "field_heat_score": 90, "bonus_score": 3, "brief_reason": "TOP1i-ADC靶向拓扑异构酶1，通过ADC形式递送强效TOP1抑制剂payload，并展现免疫刺激活性。AbbVie作为头部MNC、ADC+热门靶点机制+免疫原性亮点综合推动高分，preclinical explant数据阶段限制部分得分。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6835", "id": "I1XM_5wBX1NQZOEH-LG5", "source_drug_name": "TOP1i-ADC", "title": "TOP1i-ADC demonstrates immune-stimulating activity in colorectal cancer explants", "abstract_text": "Topoisomerase 1 (TOP1) is a ubiquitous enzyme that primarily regulates the topology of DNA by governing the relaxation of DNA supercoiling. When TOP1 is inhibited by camptothecin and its analogs, re-ligation of TOP1 cleavage complexes (TOP1cc) is prevented, leading to the accumulation of TOP1cc-associated DNA damage, inhibition of cellular proliferation, and eventual cell death. Antibody drug conjugates (ADCs) are a class of cancer therapeutics in which a potent cytotoxic payload is linked to a tumor-targeting antibody. ADCs allow direct delivery of a drug to tumor cells, thus enhancing tumor cell-specific killing. Several TOP1 inhibitor-ADCs (TOP1i-ADCs) have been approved, and others are under clinical investigation, showing efficacy in solid tumors. Beyond direct cytotoxicity, recent evidence suggests that TOP1i and TOP1i-ADCs trigger immunogenic changes in cancer cells, fostering immune activation. In studies using colorectal (CRC) cell lines treated with adizutecan, a proprietary AbbVie TOP1 inhibitor, we observed upregulation of gene pathways involved in the Type I Interferon response. Notably, adizutecan increased surface expression of immunogenic markers including MHC-I, MHC-II, CALR, and PD-L1 in CRC lines. To evaluate TOP1i-ADC-induced immune activation within a native tumor microenvironment, organotypic tumor slices from fresh human metastatic colorectal carcinoma were utilized for this study. We treated these fresh human metastatic colorectal carcinoma tissue slices with TOP1i-ADC and evaluated changes in both the tumor and immune cells by flow cytometry and spatial transcriptomics. TOP1i-ADC treatment led to reduced tumor cell proliferation and viability, and consistent activation of dendritic cells as well as CD4 T cells. CD8 T cell activation was observed in 3 out of 5 explant samples. The flow cytometry data was further supported by the secretome profile, which shows elevated levels of pro-inflammatory chemokines and cytokines such as CCL3, CXCL10, G-CSF and granzyme B (GZMB). Spatial transcriptomics analysis revealed TOP1i-ADC treatment reduced DNA replication and cell cycle gene signatures consistent with TOP1i payload release within the tumor explant. Consistent with the flow cytometry data, immune cell responses displayed dendritic cell maturation in both proximal and distal regions to the tumor cells. CD8 T cell activation, evidenced by higher granzyme B (GZMB) expression, was especially prominent in distal areas consistent with spatially distinct regional activation. Collectively, these findings support that TOP1i-ADC therapy drives potent immune activation and immunogenicity, complementing its direct antitumor effects and highlighting its promise for enhancing cancer treatment efficacy.", "source_company": "AbbVie Inc.", "source_org_type": "公司", "row_number": 9, "target_meta": "TOP1", "MOA_meta": "抗体偶联药物"}, {"drug_name": "B2-DNR CAR T cells", "company": "Gracell Biotechnologies Co. Ltd., A Member of the AstraZeneca Group", "org_type": "公司", "target": "DLL3", "modality": "CAR", "importance_level": "高", "total_score": 85.5, "institution_score": 90, "track_score": 85, "milestone_score": 80, "field_heat_score": 90, "bonus_score": 3, "brief_reason": "靶向DLL3的nanobody-based双特异性CAR-T（B2-DNR）通过DNR装甲抵抗TGFβ免疫抑制，显著提升SCLC异种移植瘤模型中的持久抗肿瘤活性。Gracell作为AstraZeneca集团成员获得高机构分，CAR-T+快速制造+热门靶点+强前临床数据支撑较高总分。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5193", "id": "Q1XM_5wBX1NQZOEH-LK6", "source_drug_name": "B2-DNR CAR T cells", "title": "Nanobody-based, DLL3-directed FAST-CAR T-cell therapy for small cell lung cancer (SCLC)", "abstract_text": "Introduction: Small-cell lung cancer (SCLC) is aggressive with poor prognosis, and current immunotherapies have limited efficacy. Delta-like ligand 3 (DLL3), expressed in ~80% of SCLC with restricted normal-tissue expression, is a promising CAR T target. We developed nanobody-based, autologous DLL3 CAR T cells armed with a dominant-negative TGFβ receptor II (DNR) to resist TGFβ-driven immunosuppression and enhance antitumor activity.\nMethods: Candidate DLL3 binders were derived from a camelid-immunized phage display library and engineered into second-generation CARs. Constructs were tested in vitro for specific lysis with target cell lines. Lead binders were screened for cross-reactivity against Notch ligands. The DLL3 epitope was mapped, and membrane-proximal binders targeting EGF3-6 were prioritized. Off-target interactions were assessed using a membrane proteome array. Multiple CARs—with varying binders/biparatopic combinations, co-stimulation domains, and hinges—were compared in short-term and repeated antigen-stimulation assays across cells with varying DLL3 levels in vitro. Lead CAR T cells with or without DNR were compared in vitro and in vivo. Top constructs advanced to testing in multiple CDX and PDX models to evaluate antitumor efficacy and safety. Manufacturing was compared between a 3-day FasTCAR and an 8-day conventional process.\nResults: Three VHH binders demonstrated high DLL3 specificity, with no cross-reactivity to Notch family ligands and no off-target binding, and similar affinity for mouse DLL3. The lead biparatopic CAR construct, B2, demonstrated superior cytotoxicity and durability in short-term and repeated antigen-stimulation assays. When armored with DNR, B2-DNR CAR T cells showed augmented persistence versus the unarmored counterparts. In vivo safety assessments showed no body-weight loss in CAR T-treated mice across multiple dose levels, suggesting a wide therapeutic index. T cells were present in the mouse pituitary pars intermedia, where DLL3-positive cells are enriched, but their DLL3 expression was largely intracellular rather than on the cell surface. B2 did not show on-target, off-tumor toxicity. B2-DNR CAR T cells rapidly cleared established tumor xenografts with high and low DLL3 expression in immunodeficient mice, correlating with robust intratumoral CD3+ T-cell infiltration. In a TGFβ-rich PDX model, B2-DNR CAR T cells outperformed the unarmored counterpart, supporting the functional benefit of DNR. The 3-day FasTCAR manufacturing process demonstrated greater efficacy and durability than the 8-day process.\nConclusions: The camelid nanobody-derived, DLL3-targeted CAR T-cell therapy manufactured by a 3-day FasTCAR process demonstrates the potential to elicit deep and durable antitumor responses with a favorable safety profile. Preclinical data for the lead candidate, B2‑DNR, support further clinical development for the treatment of SCLC.", "source_company": "Gracell Biotechnologies Co. Ltd., A Member of the AstraZeneca Group", "source_org_type": "公司", "row_number": 32, "target_meta": "DLL3", "MOA_meta": "其他"}, {"drug_name": "TRO-01", "company": "TriOar Inc.", "org_type": "公司", "target": "CLDN18.2", "modality": "ADC", "importance_level": "高", "total_score": 85.5, "institution_score": 75, "track_score": 95, "milestone_score": 85, "field_heat_score": 90, "bonus_score": 5, "brief_reason": "TRO-01为靶向CLDN18.2的ADC，采用新型TROSIG连接子和高DAR设计，在多种胃癌和胰腺癌模型中显示强劲抗瘤活性、良好PK和安全性。TriOar作为韩国新兴ADC平台型biotech虽非顶级但获Celltrion大额合作及多轮融资，CLDN18.2+ADC赛道当前极热，preclinical数据扎实具较高潜力。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4459", "id": "3VXM_5wBX1NQZOEH-LG6", "source_drug_name": "TRO-01", "title": "Preclinical characterization of TRO-01, a novel CLDN18.2-targeting ADC, with potent anti-tumor efficacy and favorable PK and safety", "abstract_text": "Claudin 18.2 (CLDN18.2) is a tight junction protein normally restricted to the gastric mucosa. Loss of epithelial polarity during malignant transformation exposes CLDN18.2 on the surface of gastric and gastroesophageal junction (G/GEJ) adenocarcinoma cells. As CLDN18.2 is highly expressed in 30–40% of G/GEJ cancers and is associated with poor prognosis, it has emerged as a promising therapeutic target for gastric cancer, where effective targeted therapies remain limited. We developed TRO-01, an antibody-drug conjugate (ADC) composed of a fully human anti-CLDN18.2 monoclonal antibody conjugated to a topoisomerase I inhibitor via the proprietary TROSIGTM linker. This cleavable, highly stable, and hydrophilic linker enables a high and uniform drug-to-antibody ratio (DAR) of 8. In vitro studies demonstrated that TRO-01 specifically binds to CLDN18.2 but not to CLDN18.1, exhibiting enhanced affinity compared with competitor antibodies, with cell binding affinities in the single nanomolar range across tested cell lines. Additionally, TRO-01 showed efficient internalization and potent cytotoxicity in CLDN18.2-positive cell lines, with IC50 values ranging from sub-nanomolar to double-digit nanomolar depending on the cell type. In vivo, TRO-01 treatment resulted in significant tumor growth inhibition (TGI) in both cell line-derived xenograft (CDX) and patient-derived xenograft (PDX) models. In the Patu8988s CDX model, a single dose of 3 or 6 mg/kg resulted in 86% and 101% TGI, respectively. In the SNU-601 CDX model, BIW x 4 dosing at 0.3 or 0.5 mg/kg resulted in 109% and 111% TGI. In two gastric and two pancreatic PDX models, TRO-01 treatment (QW x 2, 2.7 mg/kg) resulted in 89% and 93% TGI in gastric, and 75% and 84% TGI in pancreatic PDXs, with no significant body weight loss. Pharmacokinetic studies in monkeys demonstrated favorable PK properties (t1/2 = 7.2 days, AUC = 13,800 hr·μg/mL, CL = 0.364 mL/hr/kg, Vd = 0.082 L/kg at 5 mg/kg). Toxicology studies in cynomolgus monkeys revealed a favorable safety profile, with a highest non-severely toxic dose (HNSTD) of 40 mg/kg after single dosing. Collectively, these findings highlight TRO-01 as a promising therapeutic candidate for the treatment of CLDN18.2-expressing gastrointestinal cancers.", "source_company": "TriOar Inc.", "source_org_type": "公司", "row_number": 202, "target_meta": "CLDN18.2", "MOA_meta": "抗体偶联药物"}, {"drug_name": "ARC-401", "company": "Araris Biotech AG", "org_type": "公司", "target": "Nectin-4", "modality": "ADC", "importance_level": "高", "total_score": 85.5, "institution_score": 85, "track_score": 95, "milestone_score": 70, "field_heat_score": 90, "bonus_score": 8, "brief_reason": "ARC-401为靶向Nectin-4的first-in-class三payload ADC，旨在克服耐药和肿瘤异质性，显示出广谱抗瘤活性和高耐受性；机构被Taiho/Otsuka以高估值收购且有热门多payload ADC创新机制，在热门ADC+Nectin-4赛道中preclinical阶段具强里程碑潜力。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11404", "id": "6lXM_5wBX1NQZOEH-LG6", "source_drug_name": "ARC-401", "title": "ARC-401 - a triple payload first-in-class ADC against Nectin-4 designed to overcome cancer resistance and tumor heterogeneity shows broad anti-tumor activity and high tolerability in rats and non-human primates", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Araris Biotech AG", "source_org_type": "公司", "row_number": 205, "target_meta": "NECTIN4", "MOA_meta": "抗体偶联药物"}, {"drug_name": "PF-08046033", "company": "Pfizer", "org_type": "公司", "target": "GPNMB", "modality": "ADC", "importance_level": "高", "total_score": 85.5, "institution_score": 95, "track_score": 85, "milestone_score": 75, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "PF-08046033为辉瑞开发的靶向GPNMB的新型auristatin S ADC，采用低渗透性payload显著改善了NHP耐受性（剂量耐受性提升5倍）。辉瑞顶级机构+ADC热门赛道+较强的preclinical差异化数据使其整体重要性较高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5345", "id": "DlXM_5wBX1NQZOEH-LK6", "source_drug_name": "PF-08046033", "title": "PF-08046033 (GPS): A novel first in class auristatin S antibody-drug conjugate for treatment of GPNMB-expressing solid tumors", "abstract_text": "Glycoprotein non-metastatic melanoma protein B (GPNMB) is a type 1a transmembrane protein that is markedly upregulated in several cancers, including NSCLC, ESCC, HNSCC, and BRCA. GPNMB is associated with poor patient prognosis and plays diverse roles in cancer biology, contributing to processes such as cell differentiation, proliferation, invasion, and migration. Low GPNMB expression in normal tissues, contrasted with high expression in primary and metastatic tumors, makes GPNMB a compelling target for antibody-drug conjugate (ADC) therapies. A previous GPNMB-targeting ADC, Glembatumumab vedotin (GV), comprised of a monoclonal antibody (mAb) conjugated to the microtubule disrupting agent monomethyl auristatin E (MMAE), showed early signs of efficacy. However, its development was constrained by dose-limiting toxicities, the majority of which were likely driven by the released MMAE payload. We hypothesized that pairing the GPNMB-targeted mAb with the novel Auristatin S (AurS), a payload engineered to be less permeable compared to MMAE, may widen the therapeutic window. Thus, we developed PF-08046033 (GPS), a novel investigational ADC composed of the human IgG1 anti-GPNMB mAb (hCR011) conjugated to the novel microtubule disrupting agent AurS using the clinical validated, protease-cleavable MC-Val-Cit linker with an average drug-to-antibody ratio (DAR) of 4. In this study, we evaluated the expression of GPNMB across multiple solid tumors, assessed the antitumor activity of GPS in vitro and in vivo in a variety of xenograft tumor models, and examined its safety profile in non-human primate (NHP) toxicology studies. GPS bound and internalized the GPNMB/ADC complex from the surface of cancer cells, leading to release of the AurS payload that induced apoptosis following G2/M cell-cycle arrest. GPS demonstrated comparable efficacy to GV in multiple GPNMB-expressing xenograft models. Notably, in NHP toxicology studies, GPS was tolerated at 15 mg/kg, which is five-fold higher than GV. Altogether, these data support the evaluation of PF-08046033 (GPS) in a first-in-human phase 1 clinical trial for the treatment of multiple solid tumors.", "source_company": "Pfizer", "source_org_type": "公司", "row_number": 208, "target_meta": "gpNMB", "MOA_meta": "抗体偶联药物"}, {"drug_name": "ZW439", "company": "Zymeworks Inc.", "org_type": "公司", "target": "CLDN18.2", "modality": "ADC", "importance_level": "高", "total_score": 85.5, "institution_score": 85, "track_score": 95, "milestone_score": 70, "field_heat_score": 90, "bonus_score": 5, "brief_reason": "ZW439为靶向CLDN18.2的pan-RAS抑制剂ADC，真实靶点为CLDN18.2，利用ADC递送pan-RASi实现肿瘤特异性抑制RAS突变。Zymeworks作为国外头部biotech机构，ADC+CLDN18.2+pan-RAS热门组合赛道热度高，前临床数据强（高效抗瘤、无明显毒性），胰腺癌未满足需求大，综合潜力突出。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5439", "id": "DVXM_5wBX1NQZOEH-LG5", "source_drug_name": "ZW439", "title": "ZW439, a novel CLDN18.2-targeting pan-RAS inhibitor antibody drug conjugate for the treatment of RAS mutated pancreatic cancer", "abstract_text": "Pancreatic cancer remains one of the most difficult to treat cancers, with 5-year survival rates of just 13%, and there is an urgent unmet need for novel, differentiated, and effective therapeutics. Recently, encouraging progress has been made through inhibition of RAS, a key oncogenic driver mutated in over 90% of pancreatic ductal adenocarcinoma (PDAC). Antibody drug conjugates (ADCs) have demonstrated clinical success at improving the effectiveness of multiple respective classes of small molecules. The full therapeutic potential of pan-RAS inhibitors (pan-RASi) has been limited by toxicities likely arising from on-target inhibition of wild-type RAS in normal tissues, as well as by the emergence of resistance. These challenges may be improved upon by enhancing delivery of a RASi via an antibody drug conjugate mechanism. Here, we seek to leverage the ability of ADCs to enhance the delivery of a novel pan-RASi payload to tumors for improved response, and to provide a differentiated safety profile that mitigates the toxicity limitations of current small molecule pan-RASi. To this end, the novel pan-RASi ADC ZW439 is directed to CLDN18.2, a clinically validated oncology target that is highly expressed in PDAC.\nA novel potent pan-RAS inhibitor ADC platform was developed through synthesis, screening, and iterative optimisation of payloads and drug-linkers for favorable ADC biophysical properties, antitumor activity, tolerability and pharmacokinetics (PK). A novel CLDN18.2 targeted antibody was selected for optimal ADC properties including its binding and internalization to CLDN18.2 expressing cells. Tumor cell spheroids were utilized to determine the cytotoxicity of the pan-RASi ADC, and its bystander activity was determined in CLDN18.2 positive and negative tumor cell co-cultures. The antitumor activity and PK of ZW439 were evaluated in multiple mouse xenograft models.\nThe novel humanized IgG1 antibody of ZW439 features strong and exclusive binding to CLDN18.2 and demonstrates superior internalization to CLDN18.2 expressing tumor cells compared to a clinical benchmark CLDN18.2 targeted antibody. ZW439 demonstrates potent target-specific cytotoxicity to RAS-mutated tumor cells expressing a range of CLDN18.2 levels and drives effective bystander activity to antigen negative cells. In vivo, ZW439 demonstrates highly efficacious anti-tumor activity in multiple CLDN18.2 expressing xenografts and has a favourable PK profile. ZW439’s pan-RASi ADC drug-linker platform demonstrates encouraging tolerability, with no significant toxicity observed following dosing up to 200 mg/kg in mice.\nThe encouraging preclinical profile of ZW439 supports its potential as a differentiated therapeutic for the treatment of Pancreatic cancer.", "source_company": "Zymeworks Inc.", "source_org_type": "公司", "row_number": 289, "target_meta": "CLDN18.2", "MOA_meta": "抗体偶联药物"}, {"drug_name": "WuXiDARx", "company": "WuXi XDC", "org_type": "公司", "target": "未披露", "modality": "other", "importance_level": "高", "total_score": 85.5, "institution_score": 85, "track_score": 90, "milestone_score": 80, "field_heat_score": 90, "bonus_score": 5, "brief_reason": "WuXiDARx是WuXi XDC开发的专有ADC/XDC连接技术平台，针对临床验证的链间半胱氨酸位点，提供灵活DAR、高均一性和稳定性提升。机构为ADC领域领先CRDMO，ADC赛道极热且有7个ADC进入临床、多个CMC项目里程碑，综合热度高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5360", "id": "MJ7ECZ0BZznHJdntvNYd", "source_drug_name": "WuXiDARx", "title": "Empowering development of next generation ADCs & XDCs through advanced WuXiDARx conjugation technologies", "abstract_text": "Background: Antibody drug conjugates (ADCs) and various types of bioconjugates (XDCs) have garnered increasing attention over the past decade. These novel payloads and payload combinations require advanced conjugation technologies to fully achieve their therapeutic potential. Conventionally, interchain cysteine coupling serves as the most clinically validated conjugation technologies. However, such methods have two major flaws: (1) heterogeneity from stochastic coupling (except for DAR8); and (2) instability during circulation due to maleimide retro-Michael addition.\nSolutions: To address these needs, WuXi XDC has built a platform through internal development and external collaboration. This platform includes two parts: (1) WuXiDARx™ conjugation technology WuXiDARx™ conjugates at interchain cystines which are the most clinical validated site, as 13 out of 18 commercial ADCs are developed through cysteine conjugation. This technology features: • Flexible DAR choices (WuXiDAR1TM, WuXiDAR2TM, WuXiDAR4TM, WuXiDAR6TM) • Improved homogeneity: ≥ 85% for DAR1 and DAR2; or ≥ 65% for DAR4 and DAR6 • Enhanced efficacy and safety profiles • Compatibility with IgG1 mAb • Compatibility with novel ADCs (e.g., dual-payload ADCs, bispecific ADCs) and XDCs (e.g., AOCs, APCs) • Simple and robust conjugation process • Validated technology: 7 ADCs in clinical trials, 10 CMC projects, up to > 2 kg batch size (2) Thiol reactive connector technologies Conventional interchain cysteine conjugation uses maleimide connector to react with the thiol groups from the antibody. However, the reverse reaction (retro-Michael addition) may result in premature release of the payload-linkers in circulation. To solve this problem, X-LinC connector is developed to replace the maleimide connector, which has shown good plasma stability and is fully compatible with WuXiDARxTM. A different way to create homogeneous DAR4 ADCs is by using thiol-rebridging connectors. CysLink technology incorporates a stable thiol-rebridging connector into the platform. Unlike traditional connectors, the CysLink version produces ADCs with fewer thiol mismatches and half-antibody ratios, and it works with WuXiDARxTM to offer additional DAR options (e.g., DAR1).\nConclusion: The combination of WuXiDARxTM, X-LinC, and CysLink offers an integrated solution to utilize the most clinically validated conjugation sites, which is helping accelerate ADCs/XDCs pipeline development from clients.", "source_company": "WuXi XDC", "source_org_type": "公司", "row_number": 333, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "CLSP-5282", "company": "Clasp Therapeutics", "org_type": "公司", "target": "KRasG12V mutant peptide presented on HLA-A*03:01", "modality": "TCE", "importance_level": "高", "total_score": 85.5, "institution_score": 85, "track_score": 95, "milestone_score": 75, "field_heat_score": 90, "bonus_score": 5, "brief_reason": "CLSP-5282为first-in-class TCE，精准靶向KRasG12V/HLA-A*03:01新抗原，机制创新且对KRAS抑制剂耐药肿瘤仍敏感。Clasp Therapeutics为获1.5亿美元A轮融资的头部新兴biotech，TCE+热门KRAS靶点赛道热度极高，前临床数据扎实，支持临床推进。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4493", "id": "bVXM_5wBX1NQZOEH-LO6", "source_drug_name": "CLSP-5282", "title": "CLSP-5282, a first-in-class T cell engager targeting KRasG12V mutant peptide presented on HLA-A*03:01", "abstract_text": "Background: Mutant KRas is one of the most common driver oncogenes in solid tumors. Approximately 25% of pancreatic cancer, 9% of colorectal cancer (CRC), and 5% of non-small cell lung cancer (NSCLC) tumors harbor KRasG12V mutations. We describe the nonclinical characterization of CLSP-5282, a first-in-class T cell engager that selectively targets the KRasG12V[7-16] mutant peptide presented on HLA-A*03:01.\nMethods: Functional activity was assessed in vitro in co-culture assays of T cells and target cells expressing KRasG12V and HLA-A*03:01, including models with acquired resistance to Ras-targeted small molecule inhibitors. Since CLSP-5282 does not cross react with any preclinical toxicology species, an extensive panel of secondary pharmacology and in vitro toxicology studies was performed. A Jurkat reporter assay with a positional scanning peptide library was used to identify potential cross-reactivity to other peptides presented on HLA-A*03:01. Specificity was further assessed by T cell reactivity with a panel of normal human tissues and a panel of the most common Class I HLA alleles, and cytokine release in high density PBMC cultures was determined to evaluate CRS risk. In vivo anti-tumor activity of CLSP-5282 was investigated in PBMC engrafted mouse models.\nResults: CLSP-5282 induces T cell activation and target cell killing specifically against cells expressing KRasG12V and HLA-A*03:01, but not wild-type KRas. Cell lines with acquired resistance to KRas inhibitors maintain sensitivity to CLSP-5282, suggesting continued presentation of the KRasG12V neoantigen. In vitro studies did not identify potential cross-reactivity to any peptides presented on HLA-A:03:01 and showed minimal T cell reactivity or cytokine release with a panel of normal human tissues, a panel of the 50 most common Class I HLA alleles, or in high-density PBMC cultures. In vivo, CLSP-5282 induces regression of established tumors in a humanized mouse model.\nConclusions: These preclinical data support clinical evaluation of CLSP-5282 in HLA-A*03:01 positive patients with solid tumors harboring the KRasG12V mutation. CLSP-5282 is expected to be the first TCE in the clinic directed against mutant KRas, providing tumor targeting without the risk of on-target, off-tumor toxicity. Our data demonstrate the potential for CLSP-5282 to be efficacious even in the context of resistance to small molecule KRas inhibitors.", "source_company": "Clasp Therapeutics", "source_org_type": "公司", "row_number": 1248, "target_meta": "HLA-A3", "MOA_meta": "其他"}, {"drug_name": "EpiTACs", "company": "Epibiologics", "org_type": "公司", "target": "c-KIT", "modality": "bispecific antibody", "importance_level": "高", "total_score": 85.3, "institution_score": 85, "track_score": 92, "milestone_score": 75, "field_heat_score": 90, "bonus_score": 8, "brief_reason": "EpiTACs为新型双特异性抗体介导的c-KIT胞外靶向降解剂，能克服突变耐药并实现肿瘤选择性降解。机构为美国头部新兴biotech（获J&J、GV等顶级投资），平台创新性强、preclinical数据扎实（体外+CDX/PDX模型有效且HSC毒性低），赛道（eTPD+双抗+热门靶点c-KIT）热度极高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5513", "id": "GFXM_5wBX1NQZOEH-LG5", "source_drug_name": "EpiTACs", "title": "Discovery of mutation-independent cKit degrading bispecific antibodies that suppress tumor growth in preclinical models of GIST", "abstract_text": "Extracellular targeted protein degradation (eTPD) has emerged as a promising drug modality focused on the selective elimination of extracellular and transmembrane proteins. Unlike intracellular protein degraders, such as proteolysis targeting chimeras (PROTACs) and molecular glues, which rely on ubiquitin-proteasome pathways, extracellular degraders can harness a variety of internalizing receptors that can be tailored to specific targets and tumor types. EpiTACs are a novel type of extracellular targeted protein degrader (eTPD) defined as bispecific antibodies designed to bind a protein of interest (POI) with one arm and a degrading cell-surface receptor with the other. When the receptor is engaged, it carries the POI target into the cell, leading to selective degradation of the POI on receptor-expressing cells. EpiTACs combine favorable pharmacological and manufacturing properties of antibodies with the ability to engineer tissue specificity aiming to enhance efficacy while reducing off-target toxicity. To demonstrate the potential of this platform, we developed EpiTACs to the canonical receptor tyrosine kinase c-KIT. c-KIT is a critical driver of gastrointestinal stromal tumor (GIST) pathogenesis, with activating mutations representing the primary oncogenic event. Current kinase inhibitors are limited by the inevitable emergence of secondary resistance mutations. EpiTACs offer a compelling alternative by eliminating c-KIT itself, rather than merely inhibiting its activity, thereby overcoming mutation-dependent resistance and providing a potentially more durable therapeutic strategy. Importantly, c-KIT is also expressed on healthy cells, including hematopoietic stem cells (HSCs), highlighting the need for approaches that selectively target tumor cells while sparing normal tissue. We generated over 50 c-KIT-targeting EpiTACs spanning 10 degrading receptors expressed on GIST cells but absent from HSCs. These constructs were screened in tumor cell-based assays for c-KIT internalization and degradation. One such construct preserved degrading receptor expression, allowing for sustained catalytic degradation of the POI, which resulted in markedly reduced c-KIT levels and strong efficacy in vitro and in CDX and PDX mouse models. This EpiTAC demonstrates limited toxicity to HSCs, and could be used as a complementary approach as well as a front line combination opportunity with standard of care. In conclusion, eTPD of c-KIT using EpiTACs represents a promising new therapeutic modality and expands the toolbox of extracellular targeted degraders that can be applied in a target-, tissue-, and disease-specific manner.", "source_company": "Epibiologics", "source_org_type": "公司", "row_number": 325, "target_meta": "KIT", "MOA_meta": "双特异性抗体"}, {"drug_name": "anti-BCMA CAR-T", "company": "AstraZeneca", "org_type": "公司", "target": "BCMA", "modality": "CAR", "importance_level": "高", "total_score": 85.2, "institution_score": 92, "track_score": 88, "milestone_score": 68, "field_heat_score": 90, "bonus_score": 2, "brief_reason": "靶向BCMA的自体CAR-T在多发性骨髓瘤领域已有临床成功先例，AstraZeneca作为头部MNC开展的SDKO人源化小鼠模型体内评估显示捐献者特异性差异和潜在个性化筛选价值。机构顶级+热门细胞治疗赛道高分，但仍处preclinical阶段且无全新机制故总分略有扣减。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4572", "id": "-VXM_5wBX1NQZOEH-LC5", "source_drug_name": "anti-BCMA CAR-T", "title": "In vivo evaluation of autologous anti-BCMA CAR-T therapy in PBMC-humanized SDKO mice reveals donor-specific immune responses", "abstract_text": "Introduction: Autologous CAR-T therapies targeting B-cell maturation antigen (BCMA) have shown remarkable clinical success in treating multiple myeloma (MM). However, accurate prediction of patient-specific efficacy and adverse events - such as cytokine release syndrome (CRS), immune effector cell-associated neurotoxicity syndrome (ICANS) and Immune effector cell associated hemophagocytic lymphohistiocytosis-like syndrome (IEC-HS) - remains a significant and ongoing challenge. To address the need for personalized screening of CAR-T immunotherapies, we developed and tested a novel humanized mouse model using the NSG-SGM3-IL15-DKO (SDKO) strain, optimized for PBMC engraftment. This model is a new potential preclinical tool to assess individualized CAR-T efficacy and toxicity in vivo.\nMethods: We evaluated autologous anti-BCMA CAR-T therapy in vivo using five human PBMC donors in the context of an established BCMA+ tumor. For this, SDKO mice were injected intravenously with 1×10⁶ MM.1S-luc cells, a model cell line for multiple myeloma. Ten days post-tumor injection, mice were randomized based on their tumor burden and injected with 3×10⁶ PBMCs. Four hours later, mice received either PBS, 5×10⁶ autologous untransduced T cells (UT), or 5×10⁶ autologous anti-BCMA CAR-T cells. Tumor burden and body weight were monitored over 28 days. Blood samples were collected at SD1, SD2, SD5, SD15, SD21 and SD28 to assess human cell engraftment and plasma cytokine levels and tissues retrieved for histopathology.\nResults: Autologous CAR-T cells induced rapid and potent tumor regression with low toxicity, whereas UT cells failed to control MM.1S-luc tumors across all donors, with tumor progression even more severe than that observed in the PBS group. However, donor-dependent variability was observed: Donors 0935 and 1295 showed reduced CAR-T expansion, and 0935 failed to achieve complete tumor clearance. Transient tumor resurgence occurred in most CAR-T treated mice, except Donor 5263, where tumors were rapidly and permanently eliminated. In contrast, tumors metastasized to bone marrow in PBMC and UT groups. Cytokine profiling revealed both donor-dependent (IL-9, IL-12p70, IL-12p40) and donor-independent (IL-2, IL-4, IL-5, IFNγ, TNFα, IL-13) secretion patterns. Notably, IL-10 exhibited a unique dynamic: a modest spike at SD1 followed by a CAR-T-dependent decline, while PBS and UT groups showed very high IL-10 levels at SD5, suggesting a link to uncontrolled tumor burden and immune dysregulation.\nConclusion: Our results demonstrate that the SDKO PBMC humanized mouse model has the potential to be a valuable tool for preclinical CAR-T testing, enabling patient-specific evaluation of efficacy and safety, and paving the way for safer CAR‑T cells in the clinic.", "source_company": "AstraZeneca", "source_org_type": "公司", "row_number": 303, "target_meta": "BCMA", "MOA_meta": "其他"}, {"drug_name": "ZW427", "company": "Zymeworks Inc.", "org_type": "公司", "target": "Ly6E", "modality": "ADC", "importance_level": "高", "total_score": 84.5, "institution_score": 85, "track_score": 95, "milestone_score": 65, "field_heat_score": 90, "bonus_score": 8, "brief_reason": "ZW427为靶向Ly6E的ADC，搭载新型pan-RAS抑制剂payload，针对RAS突变癌症实现肿瘤特异性递送以改善小分子pan-RASi的毒性和耐药问题。Zymeworks作为国外头部biotech在ADC领域有较强积累，pan-RAS+ADC为热门赛道且具新机制亮点，preclinical数据强劲包括多模型抗瘤活性及bystander效应，但尚处早期阶段。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5412", "id": "IFXM_5wBX1NQZOEH-LO6", "source_drug_name": "ZW427", "title": "ZW427, a Ly6E-targeting antibody drug conjugate bearing a novel pan-RAS inhibitor payload for the treatment of RAS mutated cancers", "abstract_text": "Aberrant RAS signaling is implicated as an oncogenic driver in up to 30% of cancers. Mutant selective RAS inhibitors (RASi) have been clinically approved in select indications, but their durable efficacy is hampered by acquired alterations that render tumors refractory to drug. Pan-RASi are showing broad clinical promise, but their full potential has been limited by toxicities likely arising from on-target inhibition of wild-type RAS in normal tissues, as well as by the emergence of resistance. These challenges may be improved upon by optimizing delivery of a RASi via an antibody drug conjugate mechanism. Lymphocyte antigen 6 family member E (Ly6E) is a GPI anchored cell surface protein with minimal presence in normal tissues that is prevalently overexpressed in many solid tumors including those which commonly feature oncogenic RAS mutations, such as NSCLC, PDAC, and CRC. We sought to leverage the ability of an ADC to increase the delivery of a novel pan-RASi payload to tumors for improved response, and to provide a differentiated safety profile that mitigates the toxicity limitations of current small molecule pan-RASi.\nZW427 comprises a novel Ly6E-targeted humanized IgG1 antibody conjugated to a novel pan-RAS inhibitor via a cleavable linker. The anti-Ly6E antibody was discovered and optimized for ADC application, with a focus on binding, specificity, internalization and payload delivery to tumor cell lines. To study the therapeutic potential of ZW427, in vitro ADC cytotoxicity was assessed in spheroids derived from a panel of RAS mutated cancer cell lines. Internalization and spheroid penetration were evaluated, and tumor cell co-culture assays were performed to assess bystander-mediated cell killing potential. Anti-tumor activity of ZW427 was investigated in multiple RAS mutated mouse xenograft models with a range of Ly6E-expression. Pharmacodynamic aspects of RAS inhibition were also assessed.\nZW427 exhibited target specific binding to cancer cells, highly effective internalization and bystander-mediated killing. Importantly, the ADC demonstrated potent and target-specific cytotoxicity in multiple Ly6E-expressing cancer cell spheroids. A single administration of ZW427 resulted in anti-tumor activity across a range of xenograft models. The pan-RASi ADC platform that has been developed shows encouraging tolerability in mice and an imminent toxicology study of ZW427 in non-human primates will further define its safety profile. Overall, the data supports the potential of ZW427 as a novel, highly differentiated therapeutic agent against Ly6E-expressing RAS mutant cancer indications.", "source_company": "Zymeworks Inc.", "source_org_type": "公司", "row_number": 105, "target_meta": "LY6E", "MOA_meta": "抗体偶联药物"}, {"drug_name": "NRX-8766", "company": "Nurix Therapeutics", "org_type": "公司", "target": "CBL-B", "modality": "inhibitor", "importance_level": "高", "total_score": 84.5, "institution_score": 85, "track_score": 90, "milestone_score": 75, "field_heat_score": 85, "bonus_score": 8, "brief_reason": "NRX-8766为Nurix Therapeutics发现的CBL-B intramolecular glue抑制剂，通过稳定CBL-B自抑制构象增强T细胞激活并抑制肿瘤生长，机制新颖且具突破性。Nurix作为专注蛋白降解和IO的头部biotech公司，CBL-B作为新兴热门IO靶点，preclinical数据强劲且NX-1607已进入临床，综合潜力高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6697", "id": "MZ7M_5wBZznHJdnt_W7O", "source_drug_name": "NRX-8766", "title": "Discovery and characterization of CBL-B intramolecular glue inhibitors that increase T cell activation and suppress tumor growth", "abstract_text": "Background. CBL-B, a RING-type E3 ubiquitin ligase, is a master regulator of peripheral T-cell activation and a promising immuno-oncology (IO) target. Genetic ablation of CBL-B in mice leads to enhanced T-cell activation and spontaneous tumor rejection, suggesting that pharmacological inhibition of CBL-B could reverse immunosuppression in the tumor microenvironment and potentiate anti-tumor immunity. This work describes the rational discovery of intramolecular glue inhibitors targeting the auto-inhibited conformation of CBL-B.\nMethods. We designed and executed a high-throughput screening (HTS) campaign using a homogeneous time-resolved fluorescence (HTRF) assay to identify small-molecule inhibitors that stabilize the autoinhibited, closed conformation of CBL-B. Hits were validated through orthogonal HTRF and surface plasmon resonance (SPR) assays. The binding mode was elucidated by X-ray co-crystal structure. The series was optimized for affinity and properties through iterative cycles of medicinal chemistry. Lead compounds were evaluated for their ability to enhance T-cell activation and cytokine secretion in primary human T cells and for anti-tumor efficacy in a syngeneic mouse model.\nResults. HTS of >250,000 compounds yielded a singleton hit that inhibited CBL-B activation with KD = 24.12 ± 8.90 μM. Structure-guided optimization resulted in NRX-8766, with a KD of 0.033 ± 0.001 μM for CBL-B. Treatment of human peripheral blood mononuclear cells (hPBMCs), with NRX-8766 results in 3- to 4-fold increases in T-cell activation markers (CD25, CD69) and 2- to 25-fold increases in cytokine secretion (IL-2, IFN-γ, TNF-α) when stimulated with α-CD3 or α-CD33/α-CD28. In vivo, oral administration of NRX-8766 to mice bearing syngeneic CT26 tumors significantly increased T-cell activation and suppressed tumor growth.\nConclusions. These studies demonstrate that pharmacological inhibition of CBL-B reproduces the reported mouse knockout phenotype. NX-1607, a first-in-class CBL-B inhibitor, is now in clinical development as a potential cancer immunotherapy.\nKeywords: Immuno-oncology, CBL-B, molecular glue, T-cell activation, small-molecule inhibitor, high-throughput screening, tumor immunity", "source_company": "Nurix Therapeutics", "source_org_type": "公司", "row_number": 109, "target_meta": "Cbl-b", "MOA_meta": "抑制剂"}, {"drug_name": "WuXiTecan2", "company": "WuXi XDC", "org_type": "公司", "target": "未披露", "modality": "ADC", "importance_level": "高", "total_score": 84.5, "institution_score": 85, "track_score": 90, "milestone_score": 75, "field_heat_score": 90, "bonus_score": 5, "brief_reason": "WuXiTecan2为亲水性exatecan linker-payload，专为双payload ADC设计，解决疏水性导致的聚集和稳定性问题。WuXi XDC作为全球ADC CRDMO领导者（连续多年获Best CDMO/CRO奖），ADC+双payload赛道极热，展示强体外/体内疗效、耐受性及在HER2模型优于单payload，综合潜力高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5411", "id": "X1XM_5wBX1NQZOEH-LO6", "source_drug_name": "WuXiTecan2", "title": "WuXiTecan2: A hydrophilic exatecan linker-payload for dual-payload ADC discovery", "abstract_text": "Background: Exatecan, a camptothecin-derived topoisomerase inhibitor, demonstrates high potency along with robust bystander activity. Several exatecan-based ADCs against diverse targets have now entered into late-stage clinical trials. In parallel, the need to overcome resistance mechanisms have intensified interest in dual-payload ADC strategies, with exatecan emerging as a compelling payload option in these combination formats. However, its hydrophobic physicochemical properties can lead to ADC aggregation, non-specific uptake, reduced plasma stability, particularly at DAR8, or in dual-payload settings. Therefore, the introduction of hydrophilic moieties via linker design is essential to improve ADC hydrophilicity and physicochemical behavior. Here, we developed a super-hydrophilic linker payload, named WuXiTecan2, that overcomes exatecan’s hydrophobicity and shows strong efficacy and good tolerability in vitro and in-vivo, both as DAR8 ADC and in dual-payload ADC formats.\nMethods: WuXiTecan2 was conjugated to Trastuzumab at DAR8 or formulated as a trastuzumab-dual payload ADC paired with an MMAE payload using WuXiDARX Technology. The resulting ADCs were fully characterized by HIC-HPLC, SEC-HPLC, and LC-MS. The in-vitro activity was assessed across breast and gastric cancer cell lines with varied HER2 expressions. Plasma stability was evaluated in the mouse, and human plasma. In-vivo efficacy was determined in Her2 expressing CDX models, and the tolerability of trastuzumab-WuXiTecan2 ADC(DAR8) was evaluated in mice and preliminary cynomolgus monkey studies.\nResults: WuXitecan2 was conjugated to trastuzumab at DAR8 and incorporated into a dual-payload ADC pairing with MMAE payload. Both formats were successfully generated and demonstrated highly uniform conjugation profiles. Notably, the introduction of WuXiTecan2 showed excellent ADC hydrophilicity, which is very close to naked antibody. In-vitro, both ADC formats displayed sub-nanomolar IC50 across a panel of breast and gastric cancer cell lines spanning HER2 expression levels. Both DAR8 and dual-payload ADCs showed improved plasma stability in mouse and human plasma, consistent with the enhanced hydrophilicity of the linker and its stabilizing effect on the exatecan payload. In Her2-expressing CDX models, the dual-payload ADC achieved superior tumor growth inhibition relative to the single-payload DAR8 ADC at comparable doses. Treatment was well tolerated; the trastuzumab-WuXiTecan2 DAR8 ADC demonstrated acceptable tolerability in mouse studies at a single dose up to 250mg/kg,and tolerated well in preliminary cynomolgus monkey studies at 45mg/kg, Q3Wx3.\nConclusions: WuXitecan2, enabled by the hydrophilic linker moiety design, demonstrated strong efficacy, stability and tolerability, supporting its use as a promising dual-payload ADC component.", "source_company": "WuXi XDC", "source_org_type": "公司", "row_number": 239, "target_meta": "not available", "MOA_meta": "抗体偶联药物"}, {"drug_name": "GlycoConnect®", "company": "Synaffix - a Lonza Company", "org_type": "公司", "target": "未披露", "modality": "other", "importance_level": "高", "total_score": 84.5, "institution_score": 85, "track_score": 90, "milestone_score": 75, "field_heat_score": 90, "bonus_score": 5, "brief_reason": "GlycoConnect® 是 Synaffix（现为 Lonza 子公司）的临床阶段位点特异性糖基连接技术，用于制备均质、高稳定性的 bsADC，与随机偶联相比显示出优越的均一性、稳定性和体内抗肿瘤活性。机构为全球领先的 Lonza 旗下技术平台，ADC+双抗组合赛道极热，临床阶段技术+体内模型数据体现较强里程碑价值。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5395", "id": "91XM_5wBX1NQZOEH-LG6", "source_drug_name": "GlycoConnect®", "title": "Application of clinical stage GlycoConnect® technology to bispecific antibodies yields improved bispecific ADCs in comparison to randomly conjugated bsADCs", "abstract_text": "Several bispecific antibodies (bsAbs), with the ability to bind selectively and in a concerted fashion to two tumor associated antigens (TAAs) or in the form of a biparatopic antibody, have meanwhile been approved for cancer therapy. Another increasingly successful modality for anti-cancer therapy are antibody-drug conjugates (ADCs). Although typically based on random conjugation to cysteine or lysine residues, we have shown that the native glycan of monoclonal antibodies is a privileged site for attachment of cytotoxic payloads1, while the therapeutic index is further enhanced by a highly polar spacer technology (HydraSpace®)2. Complemented by a broad choice of payloads with various modes-of-action (toxSYN® platform), these technologies have jointly been applied in multiple clinical ADC programs with the most advanced now in phase 3.\nAs multiple different bsAb formats have been introduced and are currently in clinical trials3 we wanted to understand how GlycoConnect® conjugation technology would work in context of different bsAb formats to create site-specific ADCs with defined DAR. To this end, GlycoConnect® bispecific ADCs (bsADCs) were generated with high yield and purity and the successful application of the GlycoConnect® technology was demonstrated for several different bsAb formats. In addition, we will show the advantages of GlycoConnect® conjugation in generating bsADCs compared to random cysteine conjugation. GlycoConnect® bsADCs are more homogeneous than randomly conjugated bsADCs, have improved stability and provide for compelling antitumor activity in in vivo cancer xenograft models.\n1 (a) van Geel et al. Bioconj. Chem. 2015, 26, 2233-2242. (b) Wijdeven et al. MAbs 2022, DOI: 10.1080/19420862.2022.2078466. 2 Verkade et al. Antibodies 2018, 7, 12, doi:10.3390/antib7010012. 3 Herrera et al. Trends in Cancer 2024, 10, 10, doi.org/10.1016/j.trecan.2024.07.002.", "source_company": "Synaffix - a Lonza Company", "source_org_type": "公司", "row_number": 481, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "RMC-9945", "company": "Revolution Medicines", "org_type": "biotech", "target": "KRAS G12D", "modality": "inhibitor", "importance_level": "高", "total_score": 84.5, "institution_score": 85, "track_score": 95, "milestone_score": 70, "field_heat_score": 90, "bonus_score": 5, "brief_reason": "RMC-9945是Revolution Medicines开发的KRAS G12D选择性抑制剂（代表临床候选zoldonrasib），靶向热门KRAS G12D突变，属于高热度小分子抑制剂赛道。机构为国外头部biotech公司，preclinical数据显示强协同免疫治疗潜力及机制新颖，但仍处工具化合物阶段故里程碑稍低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1363", "id": "U1XM_5wBX1NQZOEH-LS6", "source_drug_name": "RMC-9945", "title": "KRASG12Dinhibition stimulates antigen presentation and potentiates mRNA-based immunotherapy in pancreatic cancer", "abstract_text": "Inhibition of constitutively-active KRASG12D, a powerful oncogenic driver in pancreatic ductal adenocarcinoma (PDAC), has been shown to sensitize tumors to T-cell-mediated immunotherapy in preclinical models. However, the influence of KRASG12D inhibition on tumor cell antigen presentation remains unclear. Therefore, we employed a multi-omic profiling workflow to investigate alterations in the proteome and peptide MHC-I ligandome (immunopeptidome) following the treatment of HPAC human cancer cells with a RAS(ON) G12D-selective inhibitor RMC-9945 (representative of investigational agent zoldonrasib), and/or IFNɣ in vitro. KRASG12D inhibition induced a unique IFN response signature and potentiated the expression of proteins involved in antigen processing and presentation. Immunopeptidomic analysis revealed a two-fold increase in both ligand abundance and diversity, reflecting the differential expression of proteins induced by KRASG12D inhibition.\nWe hypothesized that KRASG12D signaling inhibition in preclinical models could augment immune responses initiated by immunization targeting tumor antigens in vivo via the following mechanism: the release of antigens from KRASG12D-induced cell death, coupled with increased MHC-I expression on remaining tumor cells, would enhance interactions with T cells activated by immunization. To test this, we orthotopically inoculated C57Bl/6 mice with a murine PDAC-KRASG12D cell line engineered to express the model self/tumor-associated antigen gp100. Mice were then immunized with either empty ionizable lipid nanoparticles (e-iLNPs) or iLNPs packaged with mRNA encoding full-length gp100 (gp100-iLNP). Prior to and during subsequent vaccine boost doses, mice were treated continuously with either KRASG12D inhibitor RMC-9945 or vehicle. Mice treated with both gp100 mRNA-iLNP immunization and KRASG12D inhibition exhibited significant tumor regression that was sustained over time compared to either treatment modality alone. This anti-tumor response was associated with a superior antigen-specific T cell response to subsequent immunizations, the retention of functional tumor antigen-specific cytotoxic T lymphocytes in both the tumor microenvironment and local secondary lymphoid organs, and sustained MHC-I and MHC-II surface expression on tumor cells.\nThese preclinical findings underscore the dynamic nature by which PDAC antigen presentation can be modulated by KRAS signaling inhibition and IFNɣ. Combining allele-specific KRAS inhibition with tumor antigen immunization resulted in sustained tumor regression in vivo and was associated with the retention and function of tumor antigen-specific T cells. This rationalizes the combination of both approaches for enhanced anti-tumor activity, offering a strategy that is worth exploring clinically for improving outcomes in pancreatic cancer treatment.", "source_company": "UCLA David Geffen School of Medicine", "source_org_type": "大学", "row_number": 890, "target_meta": "KRAS G12D", "MOA_meta": "抑制剂"}, {"drug_name": "CAP-IL-12 LNP", "company": "Earli Inc", "org_type": "公司", "target": "未披露", "modality": "other", "importance_level": "高", "total_score": 84.5, "institution_score": 85, "track_score": 90, "milestone_score": 75, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "CAP-IL-12 LNP利用癌症激活启动子驱动肿瘤细胞特异性表达IL-12，机制新颖，通过LNP系统递送实现肿瘤微环境局部免疫激活，避免系统性毒性。Earli作为融资超1亿美元的头部国外biotech，在热门基因治疗+免疫激活赛道中preclinical展示完整肿瘤消退和免疫激活，综合潜力高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5460", "id": "j1XM_5wBX1NQZOEH-LS6", "source_drug_name": "CAP-IL-12 LNP", "title": "Systemic nanoplasmid gene therapy with engineered cancer-activated promoters selectively programs tumor cells to express inflammatory interleukins and drive antitumor immunity", "abstract_text": "Background: Earli is developing an orthogonal genetic approach to cancer treatment with systemically delivered DNA nanoplasmids engineered with synthetic cancer-activated promoters (CAPs) to selectively express therapeutic payloads in malignant cells while remaining transcriptionally inert in healthy tissues. This selectivity concentrates encoded therapeutic activity within the tumor and concomitantly avoids systemic on-target, off-tumor toxicity. Here we describe the anti-tumor effects of CAPs driving expression of specific cytokines (i.e. IL-12), delivered IV using lipid nanoparticles (LNPs). Our data demonstrate tumor selective IL-12 expression with complete ablation of syngeneic tumor growth and minimal systemic IL-12 expression or IL-12 exposure in the serum.\nMethods: DNA Nanoplasmids were engineered for exquisite CAP specificity and validated for cytokine expression in tumor cell lines and for cytokine function in reporter cells and primary immune cells. LNP-formulated constructs were tested for in vivo distribution, efficacy, immune phenotyping and expression profiling in MB49 or B16F10 syngeneic tumor models.\nResults: CAP-cytokine constructs were expressed in tumor cell lines and produced cytokines with wild type activity. When administered IV, CAP-IL-12 LNPs but not control DNA-LNPs, induced dose-dependent, robust, durable anti-tumor activity. While tissue profiling demonstrated broad extra-hepatic biodistribution of the DNA template, IL-12 mRNA expression was exquisitely restricted to tumor tissue (12 other tissues tested similarly, although IL-12 protein was present tumor tissues, serum often below CAP-IL-12-treated mice demonstrated robust til cd4\" and cd8 activation via upregulation of ki67 granzyme b. Furthermore, also upregulated mhc-i ii antigen presentation machinery multiple myeloid dc subsets, and, contrast with treatment, only gradually induced low levels systemic ifnγ without bodyweight loss or acute toxicity-associated nk cell hyperactivation.\nConclusions: Here we describe a novel genetic approach to engage the immune system directly in the tumor microenvironment by reprogramming cancer cells to produce and secrete therapeutic cytokines directly into the TME. These efforts aim to reduce on-target, off-tumor effects and increase therapeutic window compared to systemically administered protein immune agonists. Future work includes expressing combinations of different payloads and multi-component modalities from the same genetic platform.", "source_company": "Earli Inc", "source_org_type": "公司", "row_number": 935, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "GPC3 CAR-iNKT cells with PD-1 deletion", "company": "SPH Biotherapeutics (Shanghai) Limited", "org_type": "公司", "target": "GPC3", "modality": "CAR", "importance_level": "高", "total_score": 84.5, "institution_score": 85, "track_score": 90, "milestone_score": 75, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "靶向GPC3的CAR-iNKT细胞通过PD-1删除增强实体瘤抗肿瘤活性，在小鼠模型中实现肿瘤完全清除，展示异体细胞治疗潜力。机构为国内大型药企上海医药旗下子公司，赛道为热门的异体CAR细胞治疗，preclinical数据强且有GvHD无风险亮点。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3686", "id": "MJ7M_5wBZznHJdnt_W7O", "source_drug_name": "GPC3 CAR-iNKT cells with PD-1 deletion", "title": "Harnessing allogeneic CAR‑iNKT cells for next‑generation treatments in oncology and autoimmunity", "abstract_text": "Background: Chimeric antigen receptor (CAR)-engineered invariant natural killer T (iNKT) cells have demonstrated promising outcomes in clinical studies for both cancer and autoimmune disorders. Their distinctive ability to recognize and eliminate tumor cells, coupled with efficient infiltration into solid tumors and modulation of the tumor microenvironment (TME), positions them as a compelling therapeutic strategy for solid malignancies. Moreover, because iNKT cells do not trigger graft-versus-host disease (GvHD), they are particularly well-suited for allogeneic, off‑the‑shelf cell therapy approaches.\nMethods: Two CAR constructs targeting CD19 and GPC3 were independently generated to evaluate therapeutic efficacy. For CD19 CAR‑iNKT cells, NSG mice were intravenously inoculated with 1×10⁶ Nalm6 cells per mouse, allowed to engraft for two days, and subsequently treated with either a single dose or three sequential doses of 1×10⁶ CAR⁺ iNKT cells per mouse administered on days 2, 4, and 6. In parallel, the activity of GPC3 CAR‑iNKT cells engineered with PD‑1 deletion was assessed in NOG‑hIL15Tg mice. Each mouse was implanted with 1×10⁶ Hep3B cells three days prior to treatment and then received three tail‑vein injections of 18×10⁶ GPC3 CAR‑iNKT cells (50% CAR⁺) or untransduced iNKT cells on days 3, 6, and 9.\nResults: In bioluminescent imaging, three sequential doses of CD19 CAR‑iNKT cells achieved marked clearance of CD19‑positive Nalm6 cells compared with unmodified iNKT cells or a single CD19 CAR‑iNKT injection, underscoring their therapeutic potential in B‑cell malignancies and autoimmune disorders such as ALL, CLL, and SLE. In contrast, within the Hep3B xenograft model, only GPC3 CAR‑iNKT cells engineered with PD‑1 deletion,rather than conventional GPC3 CAR‑iNKT cells induced tumor regression beginning on day 10, ultimately achieving complete elimination by days 24 and 31 without evidence of graft‑versus‑host disease.\nConclusions: These findings highlight iNKT cells as a potent allogeneic platform for CAR-based immunotherapy, with broad applicability across cancer and autoimmune diseases, thereby establishing a robust basis for continued clinical investigation.\nEthics Approval: The study was approved by Medicilon’s Ethics Board, approval number SWSH(YF)2025-034.", "source_company": "SPH Biotherapeutics (Shanghai) Limited", "source_org_type": "公司", "row_number": 1158, "target_meta": "GPC3", "MOA_meta": "其他"}, {"drug_name": "BLU-020", "company": "Blueprint Medicines Corporation", "org_type": "公司", "target": "CDK2", "modality": "degrader", "importance_level": "高", "total_score": 84, "institution_score": 85, "track_score": 90, "milestone_score": 75, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "BLU-020为Blueprint Medicines开发的口服CDK2选择性小分子降解剂，针对CCNE1异常癌症，具有高选择性和体内抗瘤活性。机构为国外头部biotech（曾被Sanofi收购），PROTAC类degrader赛道+CDK2靶点在肿瘤领域热度高，前临床数据强劲且具best-in-class潜力。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8748", "id": "tlXM_5wBX1NQZOEH-LS6", "source_drug_name": "BLU-020", "title": "The discovery of BLU-020: A potent and selective degrader of CDK2 for the treatment of CCNE1 aberrant cancers", "abstract_text": "Background: Cyclin E1 is the catalytic binding partner of CDK2, which becomes aberrantly activated when CCNE1 is amplified and overexpressed, driving tumorigenesis. Tumors with aberrant cyclin E1 expression are highly dependent on Cyclin E1/CDK2 activity, presenting a distinct therapeutic opportunity. Selective degradation of CDK2 may limit off-target CDK family-driven toxicities commonly associated with pan-CDK inhibitors. We highlight the discovery of BLU-020, a potent, CDK2-selective, and kinome-sparing investigational degrader of CDK2. \nOur efforts began with the design of CDK2-targeted heterobifunctional degraders leveraging Blueprint’s proprietary inhibitor library, resulting in the identification of several potent compounds with moderate selectivity. Subsequent modifications led to improvement on both CDK family selectivity and improvement on ADME properties of the lead series. With additional efforts to optimize the degraders for projected human dose, a development candidate, BLU-020, was identified. \nResults: BLU-020 is an orally bioavailable, kinome-sparing, CDK2-selective small molecule degrader that leads to potent and sustained pRb inhibition, significant and sustained G1 cell cycle arrest, strong and selective suppression of E2F targeted genes and inhibition of cell proliferation in CCNE1-aberrant CDK2-dependent tumor cell lines. In a screen against a panel of ~100 tumor cell lines, BLU-020’s potency and selectivity was demonstrated by showing strong inhibition of CCNE1-aberrant tumor cells bearing the triple biomarker CCNE1 high/RB positive/p16 high, while completely sparing non-CDK2 dependent triple biomarker negative cell lines, with a selectivity ratio of over 500 fold. BLU-020 was able to sensitize tumor cell lines lacking p16 in combination with the CDK4/6i ribociclib. Finally, BLU-020 demonstrated robust and durable in vivo anti-tumor activity in preclinical models of CCNE1-amplified cancers such as OVCAR3 CDX model following once-daily oral administration.\nConclusion: With its potency on CDK2 and improved selectivity over other CDK family members and the kinome compared to previous reported CDK2 agents, BLU-020 has best-in-class potential for CCNE1-aberrant ovarian cancers.", "source_company": "Blueprint Medicines Corporation", "source_org_type": "公司", "row_number": 1255, "target_meta": "CDK2", "MOA_meta": "降解剂"}, {"drug_name": "AR166", "company": "Y-Biologics", "org_type": "公司", "target": "PD-1/LAG-3/IL-2v", "modality": "immunocytokine", "importance_level": "高", "total_score": 83.8, "institution_score": 70, "track_score": 92, "milestone_score": 85, "field_heat_score": 90, "bonus_score": 8, "brief_reason": "AR166为首创PD-1×LAG-3×IL-2v三特异性immunocytokine，通过cis-acting IL-2v递送实现双重checkpoint阻断并激活CD8+ T细胞，针对PD-1耐药肿瘤。Y-Biologics作为韩国头部抗体biotech，在热门IO赛道展示强劲preclinical数据包括人源化模型显著优效、安全性良好及免疫记忆，综合热度高且具FIC亮点。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4506", "id": "0FXM_5wBX1NQZOEH-LO6", "source_drug_name": "AR166", "title": "AR166, a first-in-class PD-1xLAG-3xIL-2v tri-specific immunocytokine delivering Cis-acting IL-2v to overcome immune checkpoint inhibitor resistance", "abstract_text": "Immunocytokines fusing anti-PD-1 antibody with interleukin-2 (IL-2) have demonstrated therapeutic potential in clinical settings in overcoming resistance to PD-(L)1 inhibitors. However, clinical response rates were varied, highlighting the need for improved efficacy, particularly in tumors with primary resistance to PD-1 blockade expressing high levels of LAG-3. Emerging evidence indicates LAG-3, a key immune checkpoint, acts synergistically with PD-1 to promote T cell exhaustion, while dual blockade of LAG-3 and PD-1 can reprogram CD8+ T/Tregs to enhance antitumor immunity. Here, we present AR166, a novel tri-specific immunocytokine engineered with novel Fc-silencing, delivering dual PD-1 and LAG-3 blockade while inducing PD-1-targeted CD8+ T cell activation via an optimized IL-2 variant (IL-2v).\nPatient-derived samples were profiled by flow cytometry and IHC. PD-1×LAG-3 bispecific activity and IL-2v cis-acting were assessed using PD-1/PD-L1 and LAG-3/MHC II blockade assays, and PD-1 and/or LAG-3-dependent CD8+ T cell pSTAT5 signaling. Fc-silencing was assessed using ADCC, ADCP, and CDC assays. Repeatedly stimulated PBMCs were co-cultured with tumor cells to determine T cell proliferation and activation in the presence of AR166. Patient-derived samples were treated with AR166 followed by immune cell profiling. Antitumor efficacy was evaluated in tumor-bearing (≥300 mm³) humanized syngeneic mouse models and tumor infiltrating lymphocytes were profiled. Complete responders were rechallenged with tumor cells to assess memory response. Pharmacokinetic and safety profiles were analyzed in hIL-2Rαβγ knock-in mice and cynomolgus monkeys.\nExpression of PD-1 and LAG-3 was confirmed in patient-derived tumor samples. AR166 effectively inhibited PD-1/PD-L1 and LAG-3/MHC II pathways while IL-2v showed cis-activity only when anchored to PD-1 and/or LAG-3. Assessment of Fc-silencing showed minimal Fc-dependent effector functions. AR166 elicited robust T cell proliferation and activation compared to a PD-1xIL2v competitor in an in vitro T cell exhaustion model, with similar results observed in patient-derived CD8+ T cells. AR166 showed remarkable tumor growth inhibition compared to anti-PD-1 and PD-1xIL-2v competitors in humanized mouse models that recapitulate anti-PD1 resistance with high LAG-3 expression, while immune profiling showed rapid expansion of PD-1+TCF1+CD8+ stem-like T cells. AR166 elicited durable tumor regression in a tumor rechallenge model, suggesting tumor-specific immune memory. AR166 achieved favorable safety and pharmacokinetic profiles in both mice and cynomolgus monkeys, supporting its broad therapeutic window.\nOur findings show that AR166, a first-in-class PD-1xLAG-3xIL-2v tri-specific, can exceed the efficacy of both PD-1 inhibitors and PD-1xIL-2v with good safety.", "source_company": "Y-Biologics", "source_org_type": "公司", "row_number": 1277, "target_meta": "PD1,LAG3,IL-2", "MOA_meta": "其他"}, {"drug_name": "TEAD CPI", "company": "AstraZeneca", "org_type": "公司", "target": "TEAD", "modality": "inhibitor", "importance_level": "高", "total_score": 83.5, "institution_score": 95, "track_score": 85, "milestone_score": 65, "field_heat_score": 85, "bonus_score": 0, "brief_reason": "靶向TEAD的CPI/PPI抑制剂，与KRAS抑制剂联合显示体内外差异活性，AstraZeneca作为头部MNC机构实力强。赛道为热门Hippo/YAP-TEAD通路+KRAS耐药克服组合，临床前数据扎实但in vitro与in vivo部分脱节导致里程碑分稍低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3666", "id": "B1XM_5wBX1NQZOEH-LG5", "source_drug_name": "TEAD CPI", "title": "Comparative profiling of TEAD palmitoylation and YAP-TEAD protein-protein interaction inhibitors as combination agents with KRAS inhibitors", "abstract_text": "TEAD proteins are the transcriptional effectors of the Hippo pathway that bind coactivators YAP/TAZ to activate genes involved in cell survival, proliferation, and drug resistance. Deregulation of the Hippo pathway leading to increased TEAD activity occurs in multiple cancers, including as an adaptive resistance mechanism to targeted therapies. TEAD transcriptional signatures are elevated in KRAS inhibitor-resistant cell lines, and genome wide CRISPR screens have identified multiple hits in the Hippo pathway which sensitize or confer resistance to KRAS inhibitors. Therefore, targeting the YAP/TAZ-TEAD axis has the potential to inhibit tumor growth as a monotherapy or combination strategy across diverse indications. TEAD inhibitor modalities being investigated clinically include TEAD “central pocket” palmitoylation inhibitors (CPIs) and YAP-TEAD protein-protein interaction inhibitors (PPIs). However, limited data exist on how targeting TEAD with these different classes of inhibitors compare in combination studies. We profiled the activity of a TEAD CPI and PPI alone and as combination agents with KRASG12C and KRASG12D inhibitors, assessing effects on TEAD-dependent transcription, proliferation, and tumor growth inhibition. In long-term in vitro outgrowth studies in six KRASG12C and KRASG12D cell lines, the TEAD PPI demonstrated increased growth inhibition compared to the CPI when combined with KRAS inhibitors. Additionally, the PPI re-sensitized KRASG12C-mutant NCI-H2122 cells resistant to AZD4625, a KRASG12C-selective inhibitor. Combination efficacy was observed across KRAS-mutant but not WT lines, confirming on-target activity of dual TEAD and MAPK pathway suppression. Mechanistically, the PPI suppressed TEAD-dependent transcription to a greater extent than the CPI in vitro, while reduced MAPK signaling was driven by KRAS inhibitors and not further enhanced by TEAD inhibition. Given the differences between CPI and PPI activity in vitro, combination efficacy was evaluated in vivo in three KRAS-mutant tumor models. In contrast to the in vitro results, CPI and PPIs drove equivalent regression of NCI-H2122 NSCLC xenografts when combined with the KRASG12C inhibitor sotorasib, followed by similar outgrowth once dosing was stopped. However, the robust combination efficacy observed in vitro did not translate to significant tumor growth inhibition with either TEAD modality in two KRASG12D-mutant pancreatic models, Panc04.03 and Panc10.05. Collectively, these findings suggest that while differential activity was observed between TEAD CPI and PPIs in vitro, the two modalities drove similar therapeutic benefit in vivo when combined with KRAS inhibitors. Careful exploration of the long-term benefit of TEAD and KRAS inhibitor combinations is warranted due to the disconnect between in vitro and in vivo data.", "source_company": "AstraZeneca", "source_org_type": "公司", "row_number": 4, "target_meta": "TEAD", "MOA_meta": "抑制剂"}, {"drug_name": "PNU-159,682", "company": "Synaffix/Lonza", "org_type": "公司", "target": "DNA (topoisomerase II inhibitor / DNA alkylating / virtual cross-linking)", "modality": "ADC", "importance_level": "高", "total_score": 83.5, "institution_score": 85, "track_score": 90, "milestone_score": 75, "field_heat_score": 85, "bonus_score": 4, "brief_reason": "PNU-159,682为蒽环类衍生物，通过DNA嵌入、烷基化和虚拟交联机制发挥极高细胞毒性（比多柔比星强数千倍），本次通过减弱毒性类似物结合Synaffix/Lonza的GlycoConnect®和HydraSpace®技术显著提升ADC耐受性和治疗指数，体内实现完全肿瘤消退且MTD提高8倍。机构为头部CDMO Lonza旗下平台（原Synaffix已被收购），ADC赛道及高 potency payload优化极热，preclinical数据强劲具明显技术突破亮点。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5354", "id": "gVXM_5wBX1NQZOEH-LK6", "source_drug_name": "PNU-159,682", "title": "Potency-Attenuated analogues of PNU-159,682 in conjugation with GlycoConnect® and HydraSpace® technologies provide ADCs with improved tolerability and efficacy", "abstract_text": "PNU-159,682, an oxidized secondary metabolite of nemorubicin, exhibits extraordinary cytotoxic potency, being 2,100-6,400 fold more active than the clinically established doxorubicin. Despite promising antitumor activity, antibody-drug conjugates (ADCs) utilizing PNU-159,682 have not advanced beyond phase I clinical trials. The high potency and associated poor tolerability of PNU-based ADCs likely result in suboptimal clinical dosing, limiting the potential efficacy in patients. Based on these concerns, we designed and synthesized PNU analogues with attenuated cytotoxic potency, aiming to increase the tolerability while retaining robust antitumor activity, thus improving the therapeutic index (TI). Our approach involved multiple modifications to improve the properties. Conjugation of these new PNU analogues using GlycoConnect® site-specific conjugation technology, combined with HydrasSpace® polar spacer, yielded highly homogeneous ADCs with improved PK properties. Comprehensive in vitro and in vivo studies demonstrated that ADCs incorporating these attenuated PNU analogues maintained potent antitumor efficacy, inducing complete tumor regression in relevant xenograft models. Importantly, the maximum tolerated dose (MTD) of these ADCs was increased by up to 8-fold compared to ADCs based on the original PNU-159,682 payload, translating into a significantly expanded TI. Our findings demonstrate that potency-attenuated PNU analogues, when combined with GlycoConnect® and HydraSpace® technologies, represent a promising alternative to overcome the limitations of highly potent DNA-damaging payloads. This approach may enable higher clinical dosing paving the way for next-generation anthracycline-based ADCs with broad applicability in oncology.", "source_company": "Synaffix/Lonza", "source_org_type": "公司", "row_number": 40, "target_meta": "DNA", "MOA_meta": "抗体偶联药物"}, {"drug_name": "ISM1745", "company": "Insilico Medicine", "org_type": "公司", "target": "PRMT5", "modality": "inhibitor", "importance_level": "高", "total_score": 83.5, "institution_score": 85, "track_score": 90, "milestone_score": 75, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "ISM1745为新型口服MTA-cooperative PRMT5抑制剂，针对MTAP缺失癌症具有高选择性及显著肿瘤抑制效果；Insilico Medicine作为头部AI驱动biotech公司，PRMT5-MTAP合成致死赛道热度高，项目处于PCC阶段并展示强劲preclinical数据及成药性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8696", "id": "XlXM_5wBX1NQZOEH-LO6", "source_drug_name": "ISM1745", "title": "ISM1745, an MTA-cooperative PRMT5 inhibitor for the treatment of MTAP-deleted cancer", "abstract_text": "MTAP deficiency is observed in approximately 15% of human cancers and leads to accumulation of methylthioadenosine (MTA), which competes with the methyl-donor S-adenosylmethionine (SAM) to partially inhibit post-translational methyltransferase activity of PRMT5. This molecular context creates a vulnerability in MTAP-deleted tumors, rendering them particularly susceptible to PRMT5 inhibition. MTA-cooperative PRMT5 inhibitors preferentially bind to PRMT5 when MTA occupies the SAM-binding pocket of PRMT5, thus increasing inhibitory specificity to MTAP-deficient cells. Here, we characterize ISM1745, a novel, orally bioavailable MTA-cooperative inhibitor.\nISM1745 potently inhibits formation of symmetric dimethylarginine (SDMA), the PRMT5-catalyzed methylation product, and impairs cell growth in MTAP-deficient HCT116 cancer cells in vitro (IC₅₀ = 1.1 nM), with 272-fold selectivity over MTAP wild-type HCT116 cells. In addition, Safety44 and methyltransferase panel screening indicated minimal off-target activity for ISM1745. Mechanistically, ISM1745 induces apoptosis, cell cycle arrest, and DNA damage specifically in MTAP-deleted cells, as indicated by an increased proportion of annexin V-positive cells, accumulation in the G1 phase, and elevated expression of DNA damage markers such as γH2AX. Once-daily oral administration of ISM1745 results in marked and sustained tumor growth inhibition in MTAP-deleted xenograft models. Moreover, when combined with ISM3412, an inhibitor of MAT2A, which catalyzes formation of SAM, ISM1745 exhibits significant synergistic anti-tumor activity, highlighting its promise as part of a combinatorial strategy for targeting MTAP-deficient cancers.\nIn addition to its robust biological potency and high selectivity, ISM1745 exhibits favorable drug-like properties, including optimal in vitro ADMET profiles, excellent in vivo exposure, low clearance (CL<30% Qh in non-rodent species), and moderate to high oral bioavailability across multiple preclinical species. Taken together, these findings support ISM1745 as a potent and selective MTA-cooperative PRMT5 inhibitor with robust anti-tumor efficacy, providing potential therapy for treatment of MTAP-deleted cancers.", "source_company": "Insilico Medicine", "source_org_type": "公司", "row_number": 159, "target_meta": "PRMT5", "MOA_meta": "抑制剂"}, {"drug_name": "LUA011", "company": "Shanghai Qilu Pharmaceutical Research and Development Center LTD.", "org_type": "公司", "target": "CDH17/cMET", "modality": "bispecific ADC", "importance_level": "高", "total_score": 83.5, "institution_score": 85, "track_score": 90, "milestone_score": 75, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "LUA011为靶向CDH17和cMET的双特异性ADC，通过双靶点协同提升GI肿瘤疗效并降低GI毒性，机制新颖且针对热门ADC赛道。Qilu作为国内TOP pharma（常年位列中国制药企业前5-3位）提供强力支持，preclinical数据优秀包括优于单靶ADC的疗效和良好安全性，综合热度高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5451", "id": "kFXM_5wBX1NQZOEH-LG6", "source_drug_name": "LUA011", "title": "Preclinical development of LUA011, a novel CDH17/cMET bispecific ADC with enhanced antitumor efficacy and mitigated gastrointestinal toxicity", "abstract_text": "Background: CDH17 is an emerging ADC target in gastrointestinal (GI) cancers due to its overexpression in colorectal, gastric and pancreatic tumors. However, CDH17-directed ADCs suffer on-target GI toxicities. cMET is a clinically validated target in GI malignancies with limited expression in some normal tissues. Expression profiling shows that CDH17 and cMET are frequently co-expressed in GI tumors, while seldomly co-expressed in normal tissues. Therefore, targeting both CDH17 and c-Met might improve therapeutic index and maintain or even enhance efficacy. Here we report the preclinical development of LUA011, a bispecific ADC targeting both CDH17 and cMET, with a proprietary TOPO1i payload conjugated to the antibody via a glycan-based platform.\nResults: LUA011 was selected from a panel of bispecific ADC formats based on a comprehensive evaluation of pharmacokinetic properties, in vivo efficacy, and overall developability. Both LUA011 and its unconjugated bispecific antibody moiety exhibited strong binding to CDH17-positive and cMET-positive GI cancer cell lines, with EC50 values in the nanomolar range. Rapid internalization of the antibody component was observed in multiple GI cancer cell lines expressing CDH17 and/or cMET. In vitro, LUA011 demonstrated potent and specific cytotoxicity against cell lines positive for CDH17, cMET, or both targets, with enhanced activity compared to CDH17 mono-specific ADCs in CDH17 and cMet dual-positive cell lines. LUA011 demonstrated significantly superior antitumor efficacy over CDH17- and cMET-targeting monospecific ADCs across multiple gastrointestinal CDX and PDX models with varying target expression levels. This enhanced activity was consistently observed even when compared to its own CDH17-parental ADC and a benchmark CDH17-specific ADC conjugated with the same linker-payload, underscoring that the therapeutic advantage stems from the bispecific format and the synergistic effect of dual targeting CDH17 and cMET. LUA011 exhibited high stability in human and cynomolgus monkey plasma, with minimal payload release and maintained DAR. In cynomolgus monkeys, LUA011 displayed favorable pharmacokinetics and a promising safety profile, with a maximum tolerated dose exceeding 30 mg/kg.\nConclusions: LUA011 is a novel bispecific ADC targeting both CDH17 and c-Met with favorable physicochemical properties, strong target binding, cellular internalization and potent antitumor activity in preclinical GI cancer models. Its dual targeting activity, along with its optimized payload, conjugation method, and DAR value, contribute to its strong anti-tumor efficacy, improved therapeutic index, and reduced GI toxicities. Further investigation is warranted to advance this promising ADC into clinical development.", "source_company": "Shanghai Qilu Pharmaceutical Research and Development Center LTD.", "source_org_type": "公司", "row_number": 167, "target_meta": "CDH17", "MOA_meta": "抗体偶联药物"}, {"drug_name": "DB-1329", "company": "Dualitybio Inc.", "org_type": "公司", "target": "CDCP1", "modality": "ADC", "importance_level": "高", "total_score": 83.5, "institution_score": 85, "track_score": 90, "milestone_score": 75, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "DB-1329为靶向CDCP1的ADC，CDCP1在多种实体瘤（如肺癌、胰腺癌、卵巢癌、结直肠癌）显著高表达且正常组织低表达，具有促进转移和耐药作用；DualityBio作为专注下一代ADC的头部国内biotech，已上市并与BioNTech等达成多笔高价值合作，preclinical数据强劲显示多PDX/CDX模型中优于benchmark的显著肿瘤消退和良好安全性，支持高潜力临床转化。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4042", "id": "d1XM_5wBX1NQZOEH-LO6", "source_drug_name": "DB-1329", "title": "DB-1329: A novel antibody-drug conjugate targeting CDCP1 demonstrates potent preclinical anti-tumor activity across multiple solid tumors", "abstract_text": "Background: Antibody-drug conjugates (ADCs) are designed to eradicate cancer cells while minimizing damage to healthy tissues. The identification and prioritization of viable tumor-associated antigen (TAA) targets are crucial for ADC development. To address this, we employed an integrative multi-omics approach to systematically discover and prioritize cell surface targets suitable for ADC development.\nMethods: We established an integrative framework for the identification and prioritization of tumor-associated antigen (TAA) targets. Following target identification and validation, ADCs were developed and evaluated for anti-tumor efficacy and toxicology.\nResults: Our AI-driven multi-omics-based platform identified CUB Domain-Containing Protein 1 (CDCP1), as a cell surface protein that is significantly upregulated in a large proportion of cancer cells across many solid tumors (notably lung, pancreatic, ovarian, and colorectal cancers) with limited expression in normal tissues. Given its role in promoting metastasis and therapy resistance, CDCP1 represents an attractive therapeutic target. We developed a novel antibody-drug conjugate, DB-1329, which consists of a fully human anti-CDCP1 monoclonal antibody with high affinity and specificity, conjugated via a protease-cleavable linker to a potent camptothecin-based TOP1 inhibitor payload. DB-1329 exhibited rapid and efficient internalization upon binding to CDCP1 and demonstrated potent and specific cytotoxicity in CDCP1-positive cancer cell lines. In vivo, DB-1329 induced profound and durable tumor regression across multiple patient-derived (PDX) and cell line-derived xenograft (CDX) models of lung, pancreatic, and colon cancers, demonstrating superior antitumor efficacy compared to benchmark ADC-treated animals. DB-1329 also displayed a favorable pharmacokinetic profile, was well-tolerated in toxicology studies, and exhibited a manageable safety profile.\nConclusion: These compelling preclinical results establish CDCP1-ADC DB-1329 as a promising therapeutic candidate, with potent and targeted anti-tumor efficacy against multiple CDCP1-positive solid malignancies. Our findings strongly support the continued development and clinical translation of CDCP1-ADC.", "source_company": "Dualitybio Inc.", "source_org_type": "公司", "row_number": 241, "target_meta": "CDCP1", "MOA_meta": "抗体偶联药物"}, {"drug_name": "ADC-2419", "company": "CSPC Megalith Biopharmaceutical Technology", "org_type": "公司", "target": "CD38", "modality": "ADC", "importance_level": "高", "total_score": 83.5, "institution_score": 75, "track_score": 90, "milestone_score": 85, "field_heat_score": 90, "bonus_score": 5, "brief_reason": "ADC-2419为首创CD38靶向DAC（Degrader Antibody Conjugate），通过递送超高亲和力IKZF1/3 degrader P5实现催化性蛋白降解，克服IMiD耐药。CSPC作为国内TOP pharma子公司，机构实力强；DAC+热门degrader机制赛道热度高，前临床数据优秀包括肿瘤完全消退，故综合重要性高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6482", "id": "8J7M_5wBZznHJdnt_W3O", "source_drug_name": "ADC-2419", "title": "A first-in-class IKZF1/3 degrader antibody conjugate (DAC) as a potential myeloma treatment", "abstract_text": "Antibody-drug conjugates (ADCs) deliver potent cytotoxins to tumors but are limited by off-target toxicity and resistance. This drives the development of Degrader Antibody Conjugates (DACs) platform, which combine the catalytic activity of targeted protein degradation (TPD) with the tissue specificity of antibodies. We applied this innovative approach to multiple myeloma, where most patients relapse after frontline regimens (e.g., RVd, PVd), creating a critical need for novel therapies that overcome IMiD resistance. Emerging novel IKZF1/3 degraders, which allosterically reprogram CRBN, offer a potent solution by overcoming IMiD resistance in the clinic. We hypothesized that conjugating these catalytic degraders to CD38 antibody would create a synergistic therapeutic, migrating this potent mechanism from late-line to frontline treatment. Here we describe the rational design and pre-clinical profile of ADC-2419, the first-in-class CD38-directed DAC that delivers the potent IKZF1/3 degrader P5 to tumors. From a panel of candidate payloads, we identified P5 that binds CRBN with an 80-fold higher affinity (Kd <10 nM) than lenalidomide. This ultra-high affinity enables robust ternary-complex formation even at low intracellular CRBN levels, thereby bypassing the resistance mechanisms that cripple IMiD efficacy. P5 exhibits low-picomolar degradation potency (IKZF1 EC₅₀ < 0.1 nM; IKZF3 EC₅₀ < 0.1 nM) and drives deep target degradation (≥ 90% Dmax) in tumor cells. Quantitative proteomics of >8,000 proteins confirmed exquisite selectivity; no endogenous CRBN neosubstrates were significantly reduced. Consequently, P5 shows potent cytotoxicity against MM cells (IC₅₀ < 1 nM) while exhibiting limited cytotoxicity toward PBMCs up to 1 µM. P5 exhibited favorable PK in vitro and in vivo and was well tolerated in cynomolgus monkey toxicity study, supporting its development as a next-generation payload. Therefore, conjugation of P5 to the human CD38 antibody via a cathepsin-cleavable linker generated ADC-2419. ADC-2419 demonstrates potent cytotoxicity against CD38-expressing cells in vitro. In NCI-H929 xenograft model, a single 1 mpk dose achieved complete tumor regression, outperforming parental CD38 antibody at the same dose. In the PBMC-humanized mouse model, ADC-2419 demonstrated enhanced efficacy and maintained significant superiority over the CD38 antibody. Furthermore, pronounced tumor accumulation was observed in tumor-bearing mice, aligning with the in vivo efficacy and validating the targeted-delivery capability of our DAC platform. Collectively, the robust preclinical evidence for ADC-2419, which synergizes antibody targeting with catalytic protein degradation, supports its translational promise in overcoming key limitations in myeloma treatment.", "source_company": "CSPC Megalith Biopharmaceutical Technology", "source_org_type": "公司", "row_number": 283, "target_meta": "CD38", "MOA_meta": "抗体偶联药物"}, {"drug_name": "dHuR", "company": "Degron Therapeutics Co., Ltd", "org_type": "公司", "target": "HuR", "modality": "molecular glue degrader", "importance_level": "高", "total_score": 83.5, "institution_score": 75, "track_score": 95, "milestone_score": 85, "field_heat_score": 90, "bonus_score": 5, "brief_reason": "dHuR为分子胶降解剂，靶向此前被认为不可成药的RNA结合蛋白HuR，通过招募CRBN实现降解，导致BRAF转录本异常剪接并降低BRAF蛋白水平，在BRAF突变CRC模型中显示优于现有BRAF抑制剂的抗瘤活性。机构为专注分子胶降解剂的临床阶段biotech，已与Takeda合作并推进至Phase I，赛道为热门TPD+分子胶+undruggable靶点，preclinical数据扎实且IND获批进入人体试验。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/7976", "id": "plXM_5wBX1NQZOEH-LK6", "source_drug_name": "dHuR", "title": "Molecular glue degraders of the RNA binding protein HuR to treat BRAF-mutant colorectal cancer", "abstract_text": "BRAF gain-of-function mutations, particularly BRAF(V600E), occur in approximately 10% of colorectal cancer (CRC) patients and are associated with poor prognosis and limited therapeutic options. While combined BRAF and EGFR inhibition is a standard of care, its efficacy is transient, often leading to rapid resistance and relapse. HuR is a key driver of tumor growth, invasion, and therapy resistance but was thought to be “undruggable” in the past. Here we identify novel molecular glue degraders. dHuR, as a representative, exhibited strong CRBN binding affinity and HuR degradation potency by recruiting the CRL4-CRBN ubiquitin ligase to target the RNA-binding protein HuR for degradation. Cryo-EM structural analysis revealed that dHuR created a unique benzofuran-tethered interface on CRBN, engaging a β-hairpin G-loop degron on HuR and recruiting it as a neo-substrate. Functionally, degradation of HuR by dHuR induced skipping of exon 18 in the BRAF transcript, leading to reduction in BRAF protein levels. This mechanism resulted in more effective suppression of BRAF-mutant CRC tumor growth in vitro and in vivo, including in models resistant to BRAF inhibitors. In vitro studies showed dHuR potently reduced viability in all 6 BRAF-mutant lines, while BRAF-WT cell lines remained unaffected. Mice bearing Colo205 tumors were treated with dHuR via oral gavage for 28 days. The treatment resulted in dose-dependent tumor growth inhibition. No significant changes in body weight or adverse clinical observations were reported. Furthermore, a comprehensive kinome-wide CRISPR screen identified EGFR and MEK inactivation as potent enhancers of dHuR cytotoxicity, establishing a strong rationale for combination therapy in refractory disease. Based on this compelling preclinical profile, we have advanced a clinical candidate, DEG6498. We are pleased to report the successful clearance of Investigational New Drug (IND) applications from both the U.S. FDA (IND 174949) and China's NMPA (CXHL2500454). A Phase I clinical trial has been initiated to evaluate the safety, tolerability, pharmacokinetics, and preliminary efficacy of DEG6498 in patients with advanced solid tumors, including BRAF-mutant CRC as an expansion cohort. This trial marks a significant milestone as the first-in-human study of a HuR-targeted molecular glue degrader, offering a novel therapeutic strategy with a distinct mechanism of action to overcome the limitations of current targeted therapies for this aggressive cancer subset.", "source_company": "Degron Therapeutics Co., Ltd\nDegron Therapeutics", "source_org_type": "公司", "row_number": 286, "target_meta": "ELAVL1", "MOA_meta": "其他"}, {"drug_name": "WuXi Biologics’ FolR1 TCE", "company": "WuXi Biologics", "org_type": "公司", "target": "FolR1", "modality": "TCE", "importance_level": "高", "total_score": 83.5, "institution_score": 75, "track_score": 90, "milestone_score": 85, "field_heat_score": 90, "bonus_score": 8, "brief_reason": "靶向FolR1的pH依赖型TCE，通过酸性TME选择性激活显著降低on-target off-tumor毒性，展现更宽治疗窗和优于常规FolR1 TCE的安全性。WuXi Biologics作为全球知名CRO/CDMO机构，创新pH条件性平台+CDX模型及猴毒数据支持较高开发潜力。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4501", "id": "W1XM_5wBX1NQZOEH-LG5", "source_drug_name": "WuXi Biologics’ FolR1 TCE", "title": "A novel pH dependent T cell engager platform for next generation cancer therapeutics", "abstract_text": "On-target off-tumor toxicity is a big challenge for the treatment of solid tumors using T cell engager (TCE) therapy because solid tumor associated antigens (TAAs) often expressed in not only tumor tissue but also normal healthy tissues. The acidic tumor microenvironment (TME) is a key characteristic of cancer and is leveraged to develop conditional tumor-selective therapy, which has been demonstrated with effective tumor control alongside manageable adverse events by encouraging preliminary clinical evidence emerged recently. WuXi Biologics has developed an innovative platform to identify pH dependent TAA binders that selectively bind to tumor and spare normal healthy tissues. As a clinically validated target, FolR1 overexpressed on multiple cancers, especially in ovarian and lung cancers, and associated with high-grade tumor progression & poor prognosis. Low expression of FolR1 in normal tissues is restricted to the luminal surface of lung, kidney, intestine, etc. ELAHERE, the approved FolR1 ADC demonstrated great clinical efficacy to FolR1high patients but is ineffective to FolR1low patients. FolR1 targeting TCE might be a promising therapy, though currently several TCEs stopped in pre-clinical stage due to on-target-off-tumor effect or lack of efficacy. To address these challenges, WuXi Biologics identified a novel pH-dependent FolR1 binder that binds to tumor at acidic pH over normal tissue at neutral pH, and then discovered a conditional FolR1 TCE which could kill tumor cell specifically by TME triggered activation and turning off at normal tissue, mitigate on-target-off-tumor toxicity and potentially widen therapeutic window and dose to achieve better clinical benefits. As a potential first-in-class conditional FolR1 TCE candidate, WuXi Biologics’ FolR1 TCE showed potent binding to FolR1+ tumor cells at acidic pH and very weak binding to FolR1low cells at neutral pH (representing normal tissue). Designed with fine-tuned CD3 and FolR1 affinity balance, it exhibited efficient in vitro on-tumor cytotoxicity at acidic pH and minimal cytotoxicity on normal tissue at neutral pH, and correlating cytokine levels released by T cells. WuXi Biologics’ FolR1 TCE showed dose-dependent and efficient tumor growth inhibition in human ovarian cancer and NSCLC CDX models. In exploratory cynomolgus monkey tox study, WuXi Biologics’ FolR1 TCE was well-tolerated up to 1 mg/kg with better safety profile than 16D5, one conventional benchmark FolR1 TCE which showed severe toxicity as low as 15 μg/kg. These findings suggest that WuXi Biologics’ FolR1 TCE offers significant therapeutic potential as a next-generation TCE with minimal on-target-off-tumor cytotoxicity and enhanced therapeutic window. The pH dependent design provided an innovative strategy to offer safer and more effective therapeutic overcome for solid cancer patients.", "source_company": "WuXi Biologics", "source_org_type": "公司", "row_number": 375, "target_meta": "FOLR1", "MOA_meta": "其他"}, {"drug_name": "CD19-targeted in vivo CAR-T therapy", "company": "WuXi AppTec", "org_type": "公司", "target": "CD19", "modality": "mRNA", "importance_level": "高", "total_score": 83.5, "institution_score": 85, "track_score": 90, "milestone_score": 75, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "该疗法采用tLNP递送CD19 CAR mRNA实现体内直接生成CAR-T细胞，针对CD19靶点，展示强劲的体外表达/杀伤及体内显著抑瘤、延长生存和B细胞清除效果。WuXi AppTec作为全球领先CRO/CRDMO机构，in vivo CAR-T属于2026年极高热度赛道且preclinical数据扎实，故综合评分高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9386", "id": "P57ECZ0BZznHJdntvNYd", "source_drug_name": "CD19-targeted in vivo CAR-T therapy", "title": "From tLNP selection to in vitro/vivo efficiency evaluation: In vivo CAR-T therapy", "abstract_text": "Targeted lipid nanoparticle (tLNP)-mediated in vivo CAR-T technology delivers mRNA encoding CAR directly to T cells in the body. This enables in situ engineering of T cells and provides an innovative solution to overcome the bottlenecks of traditional CAR-T therapies, such as complex processes, long cycle times, and high production costs. In this study, we first constructed the linear and circular mRNA structures of CD19 CAR and verified their expression and cytotoxicity through in vitro experiments. The results showed that, compared to linear CAR, circular CAR had a higher transfection positivity rate and expression level, as well as a stronger sustained expression ability. Additionally, the cytotoxicity results indicated that T cells transfected with circular CAR exhibited a more potent killing effect on CD19⁺ Raji cells than those transfected with linear CAR. Furthermore, by optimizing the LNP formulation and process, we obtained an unfunctionalized LNP formulation capable of efficiently transfecting activated T cells, providing a powerful tool for the validation and optimization of CAR mRNA expression. Meanwhile, CD3 or CD8 antibodies were conjugated to the lipid nanoparticle surface to construct targeted vectors such as CD3-tLNP and CD8-tLNP. By utilizing specific ionizable lipids or combining antibody conjugation with spleen-targeting formulations, tLNP can selectively target T cells while maintaining low levels of liver expression, resulting in reduced side effects. In the NALM-6 systemic model with PBMC engrafted, CD19 in vivo CAR-T can significantly inhibit tumor growth and markedly extend the survival of mice without causing weight loss. Additionally, we monitored the distribution and levels of CAR-T cells in various tissues, organs, and peripheral blood at multiple time points. Additionally, we administered in vivo CART to immunocompetent mice, humanized with CD3/CD8/CD19, and monitored the changes in B cell levels in peripheral blood and spleen after administration. During the treatment period, the amount of B cell in mice were continuously suppressed, demonstrating that in vivo CAR-T can thoroughly eliminate B cells. In summary, our study demonstrates that the integration of CAR mRNA preparation, tLNP selection and optimization, along with in vitro evaluation and in vivo tumor and autoimmune disease models, could be instrumental for the design and development of in vivo CAR-T therapies.", "source_company": "WuXi AppTec", "source_org_type": "公司", "row_number": 454, "target_meta": "CD19", "MOA_meta": "其他"}, {"drug_name": "biparatopic anti-CDH17 ADC", "company": "Earendil Labs.", "org_type": "公司", "target": "CDH17", "modality": "ADC", "importance_level": "高", "total_score": 83.5, "institution_score": 85, "track_score": 90, "milestone_score": 70, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "靶点为CDH17的双表位ADC，biparatopic设计显著提升内化效率和肿瘤抑制活性，展示preclinical优异体内外数据。机构为AI驱动的头部新兴biotech，近期获巨额融资并与Sanofi等合作，ADC+热门靶点赛道热度高，综合潜力突出。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8862", "id": "4VXM_5wBX1NQZOEH-LK6", "source_drug_name": "biparatopic anti-CDH17 ADC", "title": "Design and development of a biparatopic antibody-drug conjugate against CDH17", "abstract_text": "CDH17 is overexpressed in various adenocarcinomas, including colorectal, gastric, and pancreatic cancers. High levels of CDH17 are associated with metastatic disease and poor prognosis in patients with these malignancies, In normal tissues, the expression of CDH17 is limited. Currently, various CDH17-based therapeutics, including bispecific antibodies, ADCs, and CAR-T, are under clinical investigation for treating CRC. Here, we describe the discovery and optimization of a novel biparatopic anti-CDH17 antibody. The biparatopic antibody exhibits efficient CDH17-directed cell binding and promotes rapid internalization at a much higher efficiency than the mono-epitope targeting ADCs. Next, we conjugated the biparatopic antibody to various cytotoxic payloads. The ADCs showed selective cytotoxicity towards multiple tumor cell lines with varying levels of CDH17 expression in vitro, and potently inhibited the growth of CDH17-expressing tumor xenografts in animal models. Together, these findings indicate that our lead biparatopic anti-CDH17 ADC is a promising candidate for the treatment of cancers that overexpress CDH17.", "source_company": "Earendil Labs.", "source_org_type": "公司", "row_number": 633, "target_meta": "CDH17", "MOA_meta": "抗体偶联药物"}, {"drug_name": "CD180-directed antibody–drug conjugate", "company": "Corellia AI", "org_type": "公司", "target": "CD180", "modality": "ADC", "importance_level": "高", "total_score": 83.5, "institution_score": 75, "track_score": 90, "milestone_score": 85, "field_heat_score": 85, "bonus_score": 3, "brief_reason": "针对CD180的新型ADC在AML中显示高表达、同质性强且对正常造血干细胞低表达，体内外模型高效杀伤并在食蟹猴中耐受性好，支持进入临床。Corellia AI作为AI驱动的专注肿瘤ADC的biotech公司赛道热门、preclinical数据扎实且有明显开发优势。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4457", "id": "UFXM_5wBX1NQZOEH-LO6", "source_drug_name": "CD180-directed antibody–drug conjugate", "title": "CD180-targeting ADCs with a topoisomerase I inhibitor payload achieve strong efficacy in AML tumors", "abstract_text": "CD180 (RP105) is a type I single-pass transmembrane protein that heterodimerizes with MD-1 or MD-2 to enable stable surface expression. Characterized as an orphan Toll-like receptor predominantly expressed on mature B cells, dendritic cells, and macrophages, CD180 is also upregulated in multiple hematologic malignancies, including diffuse large B-cell lymphoma, mantle cell lymphoma, and acute myeloid leukemia (AML). Here, we identify CD180 as a novel and promising therapeutic target for AML and describe the development of a CD180-directed antibody–drug conjugate (ADC) along with its biochemical properties, antitumor activity across AML models, and pharmacokinetic and safety characteristics in non-human primates.Consistent with emerging datasets, we observed high, homogeneous CD180 expression on AML blasts, including leukemic stem and progenitor compartments, across a large cohort of primary AML specimens, with minimal to no expression on healthy hematopoietic stem cells, common myeloid progenitors, or normal tissues. We generated a fully human monoclonal antibody with high-affinity, selective binding to the human and cynomolgus CD180/MD-1 complex and no reactivity to rodent CD180.This antibody was conjugated to a topoisomerase I inhibitor with a drug-to-antibody ratio (DAR) of 8, selected for its potency and favorable stability profile in hematologic malignancies. The ADC demonstrated rapid internalization, high specificity for CD180-expressing cells, and potent cytotoxicity in AML cell lines, primary ex vivo samples, and patient-derived xenograft models, with therapeutic response strongly correlating with CD180 expression levels.In an exploratory toxicity study in cynomolgus monkeys (10, 30, and 60 mg/kg), the ADC was well tolerated, with no target-related toxicities or cytopenias observed at any dose. All clinical and histopathological findings were mild and reversible, establishing a maximum tolerated dose of 60 mg/kg. The ADC also demonstrated excellent physicochemical stability and developability properties.Together, these findings support advancement of CD180-targeted ADC therapy into clinical development for patients with CD180-positive AML.", "source_company": "Corellia AI", "source_org_type": "公司", "row_number": 707, "target_meta": "CD180", "MOA_meta": "抗体偶联药物"}, {"drug_name": "a novel bispecific antibody-drug conjugate targeting CEACAM5 and CDH17", "company": "Earendil Labs.", "org_type": "公司", "target": "CEACAM5/CDH17", "modality": "bispecific ADC", "importance_level": "高", "total_score": 83.5, "institution_score": 85, "track_score": 90, "milestone_score": 75, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "该双特异性ADC同时靶向CEACAM5和CDH17，在GI肿瘤中高表达且常共表达，展现优于单抗ADC的旁观者杀伤和广谱抗瘤活性。Earendil Labs作为AI驱动的头部biotech，近期获巨额融资并与Sanofi等合作，赛道热门且preclinical数据强劲，支持较高评分。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4531", "id": "W1XM_5wBX1NQZOEH-LS6", "source_drug_name": "a novel bispecific antibody-drug conjugate targeting CEACAM5 and CDH17", "title": "A novel bispecific antibody-drug conjugate targeting CEACAM5 and CDH17 exhibits potent anti-tumor activity and enhanced tumor-selectivity", "abstract_text": "CEACAM5 and CDH17 are preferentially expressed in gastrointestinal tumors, including more than 95% of colorectal cancers, 80% of gastric and pancreatic cancers, and 70% of cholangiocarcinomas. Moreover, these two molecules are frequently co-expressed in gastrointestinal cancers. Recent advancements in CEACAM5 and CDH17 research have unveiled their potential as the promising targets for developing novel cancer therapeutics. Here we engineered a bispecific antibody (bsAb) capable of simultaneously binding to both CEACAM5 and CDH17. The cell binding and internalization activities of the bsAb were compared to a panel of monoclonal antibodies, including M9140 analog (an anti-CEACAM5 monoclonal antibody) and TORL-3-600 analog (an anti-CDH17 monoclonal antibody), using multiple colorectal and pancreatic cancer cell lines, The bsAb was conjugated to various topoisomerase I inhibitor payloads to generate several bispecific ADC molecules (bsADCs). The activity of these bsADC was studied in vitro in tumor cell-killing assay, and in vivo in multiple CDX models of GI malignancies. We further investigated the bsADC stability in human and cynomolgus monkey plasma over a three-week period, its pharmacokinetic profile and tolerability in both SD rats and cynomolgus monkeys. The results demonstrated that the bsAb exhibits excellent developability, and the resulting bsADCs maintained high purity after conjugation with different linker-payloads. The lead bsADC candidate showed superior bystander killing activity. In GI cancer CDX models with varying CEACAM5/CDH17 expression levels, it showed tumor inhibition comparable or superior to M9140a and TORL-3-600a, suggesting a broad application in GI cancer patients. Furthermore, the candidate exhibited favorable stability in human/cynomolgus plasma and good pharmacokinetic profile and tolerability in SD rats and cynomolgus monkeys. Taken together, these data support further development and broad utility of this bsADC for GI cancer treatment.", "source_company": "Earendil Labs.", "source_org_type": "公司", "row_number": 893, "target_meta": "CEACAM5,CDH17", "MOA_meta": "抗体偶联药物"}, {"drug_name": "αCD3 heavy chain-only antibodies", "company": "Adimab", "org_type": "公司", "target": "CD3", "modality": "heavy chain-only antibody", "importance_level": "高", "total_score": 83.5, "institution_score": 85, "track_score": 90, "milestone_score": 70, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "靶点为CD3ε亚单位的新型重链抗体（HCAb/VHH），用于T细胞衔接器（TCE），机制通过独特结合角度实现高效T细胞激活，与临床验证分子活性相当。Adimab作为抗体发现领域头部平台公司，酵母技术成熟，赛道为热门TCE多特异性抗体，preclinical展示良好可开发性和功能活性，整体潜力高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5652", "id": "pVXM_5wBX1NQZOEH-LS6", "source_drug_name": "αCD3 heavy chain-only antibodies", "title": "Novel anti-CD3 heavy chain-only antibodies for use in T-cell engaging therapeutics", "abstract_text": "Background: Multispecific T cell-engager (TCEs) antibodies have shown great promise as immunotherapeutic molecules. These therapies redirect T cells to recognize and kill cancer cells through co-engagement of tumor associated antigens and a T cell antigen, often CD3. Despite their clinical efficacy, the molecular complexity of current TCEs poses challenges for drug manufacturability, developability, and achieving desirable pharmacokinetic/pharmacodynamics. Currently, all approved TCE multispecifics rely on αCD3 binders derived from conventional IgG antibodies.Heavy chain-only antibodies (HCAbs) featuring a single-domain (VHH) binding moiety are attractive alternatives to conventional IgGs in immunotherapies. The absence of a light chain in HCAbs notably simplifies multispecific development. To-date, no αCD3 HCAbs with properties comparable to best-in-class clinically approved IgGs have been reported.\nMethods: Functional αCD3 HCAbs were discovered by combining llama immunization and a novel yeast-based HCAb discovery technology. Following rounds of yeast-based HCAb selection, T cell stimulating αCD3 HCAbs were identified, humanized, and optimized to exhibit desirable drug profiles. We demonstrated the potency of these lead molecules in two bispecific formats: 1+1 αCD3 X αCD20 and as a VHH-TCR fusion using a TCR specific for the gp100 peptide HLA complex. CD3ε binding was confirmed by x-ray crystallography using one of the lead HCAbs.\nResults: This study resulted in a panel of six functional αCD3 TCEs. These molecules predominantly competed with a known CD3 epitope, recognizing the CD3ε subunit of the human T cell receptor complex with weak to strong affinities and robust drug developability profiles. Crystallographic data and subsequent structural modelling show a unique angle of approach for our lead stimulating HCAb suggesting the interaction with the TCR complex is likely limited to only the CD3δε heterodimer, as CD3γε docking is modeled to produce significant steric clashes. The panel displayed a promising functional potency range as multispecifics; with two molecules displaying comparable in vitro tumor cell killing efficacy to clinically validated molecules such as the first-in-class TCR-αCD3 fusion TCE, tebentafusp.\nConclusions: We showcase the discovery and engineering of novel αCD3 HCAbs with functional potency comparable to other clinically validated molecules. This panel of highly-developable HCAbs provide new building blocks to expand the design space for TCE multispecifics and enable the next generation of multispecific immunotherapeutics.", "source_company": "Adimab", "source_org_type": "公司", "row_number": 951, "target_meta": "CD3", "MOA_meta": "单域抗体"}, {"drug_name": "biparatopic DLL3/CD3 T cell engager", "company": "Earendil Labs", "org_type": "公司", "target": "DLL3", "modality": "TCE", "importance_level": "高", "total_score": 83.5, "institution_score": 85, "track_score": 90, "milestone_score": 75, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "靶向DLL3的biparatopic TCE，利用AI优化双表位结合，在SCLC和NECs模型中展现优于benchmark（如tarlatamab类似物）的效力和良好安全性。Earendil Labs作为获巨额融资（近8亿美元）并与Sanofi等合作的前沿AI biotech，处于热门TCE+新兴靶点赛道，前临床强度高且有明显差异化亮点。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9677", "id": "e57M_5wBZznHJdnt_W3O", "source_drug_name": "biparatopic DLL3/CD3 T cell engager", "title": "A novel AI-engineered biparatopic DLL3/CD3 T cell engager demonstrates potent preclinical efficacy and a promising safety profile", "abstract_text": "Purpose: This study aimed to develop and characterize a novel biparatopic T-cell engager (TCE) targeting DLL3 for the treatment of small cell lung cancer (SCLC) and other neuroendocrine carcinomas (NECs).\nMethods: Using an AI-engineered multispecific antibody platform, we engineered a biparatopic DLL3/CD3 TCE to bind two distinct epitopes on DLL3 while engaging CD3 on T cells. Binding affinities were systematically optimized to enhance tumor targeting and minimize off-T cell activation. The molecule was evaluated in vitro activity for T cell-dependent cytotoxicity, T cell activation, and cytokine release and in vivo efficacy using human SCLC cell lines-derived xenograft models. Safety was assessed in transgenic mice and cynomolgus monkeys.\nResults: The biparatopic DLL3/CD3 TCE demonstrated potent and specific cytotoxicity against DLL3-expressing cell lines, while limiting T cell activation and cytokine release. In murine models, it achieved significant tumor growth inhibition at lower doses than a benchmark TCE (tarlatamab analog). The molecule exhibited good tolerability at doses up to 30 mpk in transgenic mice and 10 mpk (administered via step-dosing) in monkeys, without significant adverse effects.\nConclusion: The biparatopic DLL3/CD3 TCE exhibits robust preclinical efficacy and a favorable safety profile, supporting its further development as a targeted immunotherapy for DLL3-positive SCLC and NECs.", "source_company": "Earendil Labs", "source_org_type": "公司", "row_number": 1034, "target_meta": "DLL3", "MOA_meta": "其他"}, {"drug_name": "CDK2 inhibitors", "company": "Novartis", "org_type": "公司", "target": "CDK2", "modality": "inhibitor", "importance_level": "高", "total_score": 83, "institution_score": 95, "track_score": 85, "milestone_score": 60, "field_heat_score": 80, "bonus_score": 0, "brief_reason": "Novartis针对CDK2的抑制剂研究，聚焦cyclin E/A复合物在肿瘤与GI毒性中的差异机制。机构顶级+CDK2在CCNE扩增肿瘤中潜力明确，但仍处机制探索阶段未见明确临床里程碑。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1495", "id": "bJ7M_5wBZznHJdnt_W3O", "source_drug_name": "CDK2 inhibitors", "title": "CDK2 partners with cyclin E or cyclin A to support distinct roles in cell cycle regulation: Implications for anti-tumor efficacy and potential toxicity of CDK2 inhibitors", "abstract_text": "Cyclin-dependent kinase 2 (CDK2) is the primary regulator of the S phase of the cell cycle, phosphorylating numerous substrates involved in controlling DNA replication origin firing and fork progression. CDK2 initially becomes activated in late G1 via binding to cyclin E (CCNE1/CCNE2), and contributes to phosphorylating RB1 to drive G1/S transition. As S phase progresses, CDK2 activity becomes increasingly dependent on cyclin A (CCNA2) to support the completion of DNA replication and promote activation of CDK1 in the G2 phase. In certain physiological and pathological circumstances, cyclin E overexpression has been shown to hyperactivate CDK2 and promote endoreduplication, inhibit cellular senescence, and/or override cell cycle checkpoints. Many of these features are hallmarks of cancer cells; indeed, copy number amplification of CCNE1 or CCNE2 are observed in subsets of solid tumors (e.g. gastroesophageal, ovarian, and breast cancers), highlighting CDK2 as a promising therapeutic target in these contexts. However, the development of CDK2 inhibitors has been hindered by dose‑limiting gastrointestinal (GI) toxicities, and it is unclear whether this is caused by off-target (e.g. CDK1) or on‑target inhibition of one or more CDK2-cyclin complexes. Using a combination of genetic and pharmacologic perturbations, we investigated how the different CDK2-cyclin complexes contribute to cell cycle regulation in both cancer and normal GI cell models. Our findings shed light on the underlying mechanisms by which CDK2 inhibition contributes to both anti-cancer efficacy and normal tissue toxicity.", "source_company": "Novartis", "source_org_type": "公司", "row_number": 1022, "target_meta": "CDK2", "MOA_meta": "抑制剂"}, {"drug_name": "PD-1xVEGFxIL-2 trispecific immune modulator", "company": "WuXi Biologics", "org_type": "公司", "target": "PD-1/VEGF/IL-2", "modality": "trispecific antibody", "importance_level": "高", "total_score": 82.5, "institution_score": 75, "track_score": 95, "milestone_score": 75, "field_heat_score": 90, "bonus_score": 8, "brief_reason": "该trispecific分子同时靶向PD-1、VEGF和优化mutein IL-2，构建新一代“super PD-1”免疫调节剂，具有优化的安全性和显著增强的抗肿瘤活性。WuXi Biologics作为国内头部生物药CDMO/开发机构，在热门多特异性抗体赛道上展示出强preclinical差异化优势和优于对照分子的疗效与耐受性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4534", "id": "NVXM_5wBX1NQZOEH-LK6", "source_drug_name": "PD-1xVEGFxIL-2 trispecific immune modulator", "title": "Novel PD-1xVEGFxIL-2 trispecific immune modulator with superior safety and greater efficacy", "abstract_text": "PD-1 antagonist antibodies have demonstrated significant success in the clinic. However, low response rate and high cancer recurrence requires the development of next-generation immunotherapies. Bispecific immune modulators PD-1xVEGF and PD-1xIL-2 molecules have shown promising clinical improvement over PD-1 antagonist antibodies, particularly in populations resistant to PD-1 monotherapy. VEGF, a soluble dimer enriched in the tumor microenvironment (TME), plays a crucial role in angiogenesis and tumor growth. Local enrichment of PD-1xVEGF bispecific antibodies by VEGF dimers could further potentiate the efficacy of PD-1 blockade. On the other hand, IL-2 of PD-1xIL-2 molecules can be cis-presented on PD-1-expressing T cells, expanding tumor-specific T cell populations and enhancing the functions of PD-1 antibodies. We therefore built a novel PD-1xVEGFxIL-2 trispecific immune modulator that combines the biologic functions of all three. We have optimized the trispecific format to retain the affinity and potency of both VEGF and PD-1 blockers. The proprietary IL-2 mutein has over 1000X attenuated IL-2Rβγ binding and muted CD25 binding to ameliorate systemic immunotoxicity on non-specific T and NK cells in the periphery. The sub-nanomolar anti-PD-1 antibody then directs IL-2 mutein to PD-1+ T cells and effectively replaces the natural function of CD25. Thus, proprietary IL-2 mutein specifically acts on PD-1-expressing tumor-specific T cells to expand effector populations. VEGF neutralization suppresses angiogenesis and potentiates the potency of PD-1 blockade. These creates a “super PD-1” next-generation immune modulator. PD-1xVEGFxIL-2 trispecific has been fully characterized. The potency of the trispecific for PD-1 and VEGF blockades were comparable to the respective monoclonal antibodies. The proprietary IL-2 mutein bound weakly to human IL-2Rβγ, with equivalent affinity to cynomolgus and mouse IL-2Rβγ. This IL-2 variant was inert on primary pan T cells and did not activate Treg cells, but induced potent activation of PD-1+ T cells. In addition, PD-1xVEGFxIL-2 enhanced immune activation of T cells induced by A375 tumor cells in a co-culture system. In an exploratory toxicity study, the attenuated IL-2 mutein supported a higher maximum tolerated dose for the trispecific than IBI363 in cynomolgus monkeys, which matched the optimal therapeutic doses for PD-1 and PD-1xVEGF antibodies. In mouse efficacy studies, PD-1xVEGFxIL-2 exhibited significantly greater efficacy than both PD-1xVEGF and PD-1xIL-2 in PBMC-engrafted CDX model and mouse syngeneic models. In summary, WuXi Biologics has developed a novel PD-1xVEGFxIL-2 trispecific molecule. This potent next-generation immune modulator shows great potential for further clinical investigation.", "source_company": "WuXi Biologics", "source_org_type": "公司", "row_number": 28, "target_meta": "PD1,VEGF-A,IL-2", "MOA_meta": "三特异性抗体"}, {"drug_name": "optimized analogs", "company": "Talus Bio", "org_type": "公司", "target": "TBXT (Brachyury)", "modality": "inhibitor", "importance_level": "高", "total_score": 82.5, "institution_score": 75, "track_score": 90, "milestone_score": 85, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "药物为针对转录因子TBXT(Brachyury)的共价小分子抑制剂，TBXT是chordoma的关键驱动因子且在部分神经内分泌癌中异常表达，Talus Bio作为专注undruggable转录因子的创新biotech平台公司已实现in vivo肿瘤抑制。打分依据：国外头部biotech平台型公司+热门转录因子靶向+preclinical强效PDX模型数据+罕见病+扩展潜力。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5649", "id": "Zp7M_5wBZznHJdnt_W3O", "source_drug_name": "optimized analogs", "title": "Targeting Brachyury with small molecules: A new therapeutic paradigm for chordoma and neuroendocrine carcinomas", "abstract_text": "Chordoma is a rare cancer arising from embryonic notochord remnants, most often in the sacrum and cervical spine. Although surgery and radiation are standard treatments, complete removal is frequently not possible and recurrence is common, leaving patients without effective targeted therapies. A defining molecular hallmark of chordoma is the aberrant reactivation of the transcription factor (TF) Brachyury (TBXT), a developmental regulator normally silenced in adult tissues. TBXT functions as a lineage-survival factor, driving tumor initiation and progression and establishing itself as both a diagnostic marker and compelling therapeutic target.However, TFs like TBXT are inherently difficult to drug due to their structural disorder and dependence on chromatin context. To overcome these barriers, we developed TF-Scan, a proteome-wide mass spectrometry platform that directly quantifies TF chromatin occupancy in live cells, enabling functional assessment and therapeutic targeting of TFs that were previously considered undruggable.Using TF-Scan, we discovered TAL61, a first-in-class covalent small-molecule hit that selectively binds TBXT and displaces it from chromatin. We initiated an iterative medicinal chemistry campaign, generating multiple analog series with improved covalent engagement, potency, and drug-like properties. Lead compounds strongly suppressed TBXT-dependent transcriptional programs and showed potent cytotoxicity in TBXT-expressing chordoma cell lines while sparing TBXT-negative controls. In vivo, optimized analogs produced robust tumor growth inhibition in UCH1 xenografts and the CF-365 patient-derived xenograft model, with excellent tolerability and durable pharmacodynamic activity.Transcriptomic analyses of TCGA, cBioPortal, and CRO datasets revealed aberrant TBXT expression in subsets of NECs, including Merkel Cell Carcinoma and Small Cell Lung Cancer. Ongoing work using cancer cell lines and patient-derived organoids is defining TBXT dependency in these diseases, suggesting that TBXT may serve as a broader lineage survival factor.Together, these results establish TF-Scan as a powerful TF drug discovery- platform and demonstrate the feasibility of pharmacologically targeting TBXT. Our covalent inhibitors show potent, selective antitumor activity in chordoma and point to new therapeutic opportunities in neuroendocrine cancers lacking targeted treatments.", "source_company": "Talus Bio", "source_org_type": "公司", "row_number": 85, "target_meta": "TBXT", "MOA_meta": "抑制剂"}, {"drug_name": "BH-501284", "company": "BlossomHill Therapeutics, Inc.", "org_type": "公司", "target": "pan-KRAS", "modality": "inhibitor", "importance_level": "高", "total_score": 82.5, "institution_score": 75, "track_score": 95, "milestone_score": 75, "field_heat_score": 90, "bonus_score": 5, "brief_reason": "BH-501284为非共价pan-KRAS抑制剂，靶向多种KRAS突变体（包括G12D/V/C等），具有picomolar亲和力和耐受生长因子抵抗的独特优势。机构为2020年成立的美国临床阶段biotech，已获超2.5亿美元融资且团队有FDA批准药物经验，KRAS pan-inhibitor赛道极热且preclinical数据强劲（包括多种模型肿瘤回归），综合潜力高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6700", "id": "oZ7M_5wBZznHJdnt_W3O", "source_drug_name": "BH-501284", "title": "Discovery and characterization of BH-501284: A non-covalent, pan-KRAS inhibitor for treatment of diverse KRAS-mutant tumors", "abstract_text": "KRAS mutations are among the most prevalent oncogenic drivers, representing 25% of human cancers. While recently approved covalent KRAS G12C inhibitors have demonstrated meaningful clinical benefit, no targeted therapies are currently approved for other KRAS variants. Consequently, a large portion of the KRAS-driven patient population, including those with pancreatic carcinoma (PDAC), colorectal cancer (CRC), and non-small cell lung cancer (NSCLC), remain underserved. Furthermore, available G12C inhibitors have modest potency and limited durability of effect in clinic. Research attributed these modest outcomes to adaptive resistance mechanisms associated with secondary KRAS mutations or activation of bypass pathways. This resistance, along with unmet medical needs, has driven the development of new KRAS-directed therapies capable of targeting multiple KRAS mutants. Here, we describe BH-501284, a potent, selective, orally available, non-covalent, pan-KRAS inhibitor, targeting the allosteric switch-II pocket of KRAS. BH-501284 inhibited cell viability and suppressed ERK phosphorylation in KRAS-mutant cells (G12D/C/V/S, G13D) and KRAS WT amplified cells with low to sub-nanomolar activity. BH-501284 also demonstrated greater than 300-fold selectivity against both HRAS and NRAS and showed no anti-proliferative activity in non-RAS driven cells. Raf1 effector binding assay data showed BH-501284 to bind KRAS mutants in the inactive (OFF) state, with binding affinity in the picomolar range as measured by SPR. Cellular wash off studies confirmed that BH-501284 tightly engaged KRAS, similar to covalent inhibitors. This unique target engagement allows BH-501284 to more comprehensively reduce active KRAS proteins than other reversible KRAS (ON) inhibitors. Importantly, the anti-proliferation activity of BH-501284 was only minimally affected by growth factors (e.g. EGF) that drive KRAS into the active state and lead to resistance. Durable and potent activity of BH-501284 was also observed in cell-derived xenograft (CDX) tumor models with KRAS G12D, G12V, and G12C mutations, covering NSCLC, CRC, and PDAC. PK profiling revealed good oral bioavailability of BH-501284 in multiple species and dose dependent plasma exposures in mouse xenograft tumor models. Lastly, BH-501284 showed synergistic effects with inhibitors of EGFR, FAK/SRC, and others in combination studies. Altogether, these findings position BH-501284 as a strong candidate for further development.", "source_company": "BlossomHill Therapeutics, Inc.", "source_org_type": "公司", "row_number": 107, "target_meta": "KRAS", "MOA_meta": "抑制剂"}, {"drug_name": "BCG040", "company": "Biocytogen", "org_type": "公司", "target": "B7-H4", "modality": "ADC", "importance_level": "高", "total_score": 82.5, "institution_score": 75, "track_score": 90, "milestone_score": 80, "field_heat_score": 85, "bonus_score": 8, "brief_reason": "BCG040为靶向B7-H4的双表位ADC，采用新型TOP1抑制剂payload并展现双表位设计促进受体簇集和快速内化，在异质性肿瘤PDX模型中显示优于基准ADC的持久肿瘤消退和良好成药性。机构为国内知名抗体平台biotech，赛道为热门ADC+新兴B7-H4靶点且preclinical数据强劲，综合热度高并有明确创新亮点。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5441", "id": "7FXM_5wBX1NQZOEH-LC5", "source_drug_name": "BCG040", "title": "BCG040, a novel B7-H4-targeting biparatopic ADC, demonstrates superior preclinical efficacy in heterogeneous tumors", "abstract_text": "B7-H4 (VTCN1) is overexpressed in many epithelial malignancies, particularly in ovarian, breast, biliary tract, and pancreatic cancers. These tumors are often resistant to both chemotherapy and immunotherapy, due to their aggressive nature and poor prognosis. Here, we present BCG040, a novel first-in-class, fully human IgG1κ biparatopic B7-H4 ADC. BCG040 binds to two non-overlapping B7-H4 epitopes and is conjugated to the potent topoisomerase I (TOP1) inhibitor BCPT02 (DAR≈8) via a hydrophilic protease-cleavable linker. In vitro, BCG040 showed nanomolar affinity for B7-H4, superior to Hu2F7 and SGN-B7H4V benchmark analogs, with fully human/cynomolgus cross-reactivity and no off-target binding to other B7 family members. BCG040 exhibited stronger binding and more rapid internalization than the two analogs in breast and ovarian cancer cells. In vivo, a single low dose of BCG040 showed durable tumor regressions (~40 days) in breast cancer PDX models and significant efficacy in pancreatic cancer PDX models, outperforming other ADCs such as Hu2F7, SGN-B7H4V, or FPA150 (conjugated with MMAE or BCPT02). This potent efficacy was achieved without observable toxicity and was supported by a favorable pharmacokinetic (PK) profile. Furthermore, this drug demonstrates excellent developability. The enhanced therapeutic activity of BCG040 is attributed to its unique biparatopic design, which promotes receptor clustering and accelerated intracellular trafficking, leading to enhanced delivery of payload. Notably, BCPT02-containing ADCs exhibited potent antitumor activity in heterogeneous PDX tumors, whereas MMAE-based conjugates were ineffective. These findings underscore the potential of BCG040 as a promising therapeutic candidate for the treatment of pancreatic, biliary tract, ovarian, and breast cancers.", "source_company": "Biocytogen", "source_org_type": "公司", "row_number": 152, "target_meta": "B7-H4", "MOA_meta": "抗体偶联药物"}, {"drug_name": "HEC228032", "company": "HEC Pharma Co. Ltd", "org_type": "公司", "target": "pan-RAS (ON)", "modality": "molecular glue", "importance_level": "高", "total_score": 82.5, "institution_score": 70, "track_score": 95, "milestone_score": 80, "field_heat_score": 90, "bonus_score": 5, "brief_reason": "HEC228032为口服pan-RAS(ON)抑制剂，通过分子胶机制靶向多种RAS突变体（包括G12D/V等），具有广谱抗肿瘤潜力。HEC Pharma作为中国头部创新药企之一，在热门pan-RAS赛道推进有力，体外/体内数据优于竞品RMC-6236，preclinical强度高且展示临床开发潜力。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8828", "id": "ZJ7M_5wBZznHJdnt_W7P", "source_drug_name": "HEC228032", "title": "HEC228032, an orally bioavailable molecular glue pan-RAS (ON) inhibitor with highly potent anti-tumor efficacy", "abstract_text": "Background:​ The RAS oncogene, one of the most frequently mutated drivers in human cancer, is pathogenic in approximately 25% of malignancies, with particularly high prevalence in pancreatic ductal adenocarcinoma, colorectal carcinoma, and non-small cell lung cancer. Approved RAS inhibitors are predominantly limited to the KRAS G12C mutation, leaving a substantial patient population with other KRAS mutations (e.g., G12D, G12V, G13D, Q61R, etc.) or NRAS/HRAS mutations underserved. The emergence of resistance to these agents further underscores the critical need for broad-spectrum pan-RAS inhibitors.\nMethods:​ The affinity of HEC228032 for Cyclophilin A (CypA) and KRAS mutants (G12C/D/V, etc.), as well as its disruption of RAS-RAF interactions, was evaluated using HTRF binding assays. Its anti-proliferative activity was assessed via CTG assays in tumor cell lines. Pharmacodynamic and anti-tumor efficacy were investigated in multiple KRAS-dependent xenograft models in vivo.\nResults:​ HEC228032 exhibited high binding affinity for CypA and KRAS mutants (G12C, G12V, G12D, etc) and potently disrupted KRAS-RAF interactions. It demonstrated superior in vitro potency compared to RMC-6236, inhibiting proliferation across multiple RAS-mutant cell lines with sub-nanomolar IC50 values. In KRAS-mutant xenograft models (including PK59 (G12D), HPAC (G12D), and LU99 (G12C)), HEC228032 administered orally once daily at 3-10 mg/kg induced dose-dependent tumor regression, with good tolerability over 21 days. Furthermore, HEC228032 achieved higher oral exposure than RMC-6236 in mice, rats, and beagle dogs.\nConclusions:​ HEC228032 is a promising pan-RAS(ON) inhibitor, characterized by potent antitumor activity against diverse RAS mutants, favorable pharmacokinetic properties, and an excellent tolerability profile, supporting its strong potential for clinical development.", "source_company": "HEC Pharma Co. Ltd", "source_org_type": "公司", "row_number": 166, "target_meta": "Ras", "MOA_meta": "分子胶"}, {"drug_name": "KAT2 catalytic inhibitor", "company": "Pfizer, Inc.", "org_type": "公司", "target": "KAT2A/B", "modality": "inhibitor", "importance_level": "高", "total_score": 82.5, "institution_score": 95, "track_score": 75, "milestone_score": 70, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "靶向KAT2A/B的first-in-class小分子催化抑制剂，通过表观遗传调控破坏MM肿瘤转录程序并增强免疫原性。Pfizer顶级机构+较高preclinical数据强度+新表观机制带来较高综合价值。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/7978", "id": "qFXM_5wBX1NQZOEH-LS6", "source_drug_name": "KAT2 catalytic inhibitor", "title": "First in class catalytic inhibitor of KAT2A/B demonstrates anti-tumor activity in multiple myeloma", "abstract_text": "KAT2A/B are lysine acetyltransferases that function as catalytic members of the SAGA and ATAC protein complexes, which are lineage dependencies in several tumor types including multiple myeloma (MM). Here we describe a first-in-class, small molecule catalytic inhibitor targeting the lysine acetyltransferases KAT2A and KAT2B. KAT2 inhibition disrupts oncogenic transcriptional programs, including MYC and E2F pathways, leading to growth arrest in multiple myeloma. KAT2 catalytic inhibition reduces chromatin accessibility through the loss of H3K9ac and shows single-agent activity across a panel of MM cell lines. KAT2 inhibition demonstrates tumor growth inhibition as a monotherapy in both immune modulatory drug (IMiD) sensitive and resistant multiple myeloma tumor models with good correlation with reduction of H3K9ac in vivo. KAT2 inhibition has synergistic effects with IMiDs in vitro and demonstrates increased tumor growth inhibition in combination with pomalidomide and dexamethasone in vivo. Additionally, KAT2 inhibition enhances tumor immunogenicity by activating interferon regulatory factors (IRFs) and upregulating interferon-stimulated genes (ISGs). Using a syngeneic mouse model of MM, KAT2 inhibition alters the tumor microenvironment through increased infiltration of pro-inflammatory immune cells, resulting in tumor growth inhibition and enhanced survival in combination with a mBCMA-CD3 bispecific antibody. KAT2 catalytic inhibition represents a novel therapeutic approach targeting epigenetic regulation of tumor intrinsic and immune pathways in hematologic malignancies.", "source_company": "Pfizer, Inc.", "source_org_type": "公司", "row_number": 259, "target_meta": "KAT2A,KAT2B", "MOA_meta": "抑制剂"}, {"drug_name": "VHH-based T-cell-engaging bispecifics targeting TCRα/β constant-region interface", "company": "Adimab, LLC", "org_type": "公司", "target": "TCRα/β constant-region interface", "modality": "bispecific antibody", "importance_level": "高", "total_score": 82.5, "institution_score": 85, "track_score": 90, "milestone_score": 70, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "药物通过靶向TCRα/β恒定区界面实现pan-αβ T细胞激活，提供新型TCE机制，potency媲美或优于CD3基准对照，具有结构明确和跨物种反应性等亮点。Adimab作为抗体发现领域头部平台公司（多款药物进入临床/获批），赛道为热门TCE创新方向，preclinical数据强劲，综合热度高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4526", "id": "CFXM_5wBX1NQZOEH-LG5", "source_drug_name": "VHH-based T-cell-engaging bispecifics targeting TCRα/β constant-region interface", "title": "Pan-αβ-T-cell reactive anti-TCR VHH bispecifics demonstrate potent cytotoxicity through novel constant region targeting", "abstract_text": "Introduction: All approved T-cell engagers target CD3ε, but alternative engagement sites on the TCR complex may yield differentiated functional properties. We developed VHH-based T-cell-engaging (TCE) arms that bind a previously unexploited quaternary epitope formed at the TCRα/β constant-region interface. These binders exhibit pan-αβ-T-cell reactivity with inherent human-cynomolgus cross-reactivity.\n Methods: Anti-TCR VHHs were identified using yeast-based selections against recombinant human and cynomolgus TCRα/β heterodimers, employing both synthetic libraries and llama immunization. Affinity optimization of VHHs maintained cross-species recognition. Epitope mapping was performed using TCR constant-region mutant libraries generated by error-prone PCR. Structures of VHH-TCR complexes were solved. Bispecifics incorporating anti-tumor associated antigen (TAA) domains were assessed in T-cell-dependent cytotoxicity (TDCC) assays across tumor models and benchmarked against clinical CD3 controls.\n Results: Multiple VHH lineages that recognize a conserved quaternary epitope at the TCRα/β constant-region interface were isolated, providing TRBC1/C2 coverage and human-cynomolgus cross-reactivity. Structural analyses established the binding mode. Despite moderate monovalent affinities, anti-TCR bispecifics demonstrated potent TDCC activity comparable to or exceeding benchmark CD3 bispecifics and clinically active controls. Functional activity was confirmed in both human and cynomolgus assay systems, including preliminary cytokine readouts.\n Conclusions: VHH-based bispecifics that target a quaternary epitope within the TCR constant region constitute an emerging class of T-cell-engagers with potent cytotoxic activity and broad αβ-T-cell coverage. The combination of TRBC1/C2 inclusivity, structural definition, and human-cynomolgus cross-reactivity positions TCR constant-region targeting as a promising alternative for next-generation T-cell-redirecting therapeutics.", "source_company": "Adimab, LLC", "source_org_type": "公司", "row_number": 318, "target_meta": "TCR", "MOA_meta": "双特异性抗体"}, {"drug_name": "lead bsADC", "company": "Earendil Labs", "org_type": "公司", "target": "EGFR/PDL1", "modality": "bispecific ADC", "importance_level": "高", "total_score": 82.5, "institution_score": 85, "track_score": 90, "milestone_score": 70, "field_heat_score": 85, "bonus_score": 3, "brief_reason": "药物为EGFR/PDL1双靶点bsADC，结合免疫检查点阻断与靶向细胞毒杀伤，具有协同机制潜力；Earendil Labs作为AI驱动的头部新兴biotech，近期获巨额融资并与Sanofi等合作，ADC+双抗赛道热度高，体外/体内数据优于对照ADC，但仍处preclinical阶段。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9436", "id": "M1XM_5wBX1NQZOEH-LK6", "source_drug_name": "lead bsADC", "title": "Engineering and preclinical development of a differentiated EGFR/PDL1 bispecific ADC for the targeted therapy of solid tumors", "abstract_text": "Both EGFR and PDL1 are well-established therapeutic targets for a broad range of malignancies. Nevertheless, their therapeutic efficacy remain limited, as many patients are either refractory to or develop resistance during the course of treatment. EGFR and PDL1 are frequently co-expressed in multiple tumors, where they play key roles in promoting tumor progression and immune evasion. Notably, PDL1 expression is modulated by EGFR signaling, and the significant crosstalk between EGFR and PDL1 signaling has been reported. In this study, we developed a bispecific antibody (bsAb) targeting both EGFR and PDL1. The bsAb demonstrated enhanced binding avidity towards PDL1+/EGFR+ cancer cells, with higher efficiency of internalization, and more potent EGFR‑directed blockade of PD1/PDL1 interaction. Several bsAb ADCs were generated by conjugating with various cytotoxic payloads. In vitro data demonstrated that the lead bsADC induced potent antitumor activity and strong bystander killing activity. Importantly, no Immunotoxicity was observed on PDL1+ human antigen‑presenting cells. In vivo efficacy studies demonstrated that the lead bsADC achieved superior antitumor activity compared with MRG003 analog (an anti-EGFR ADC) and the clinical-stage PDL1V analog (an anti-PDL1 ADC) in multiple CDX models.", "source_company": "Earendil Labs", "source_org_type": "公司", "row_number": 518, "target_meta": "EGFR,PDL1", "MOA_meta": "抗体偶联药物"}, {"drug_name": "BCMA/CD70 Dual CAR T cells", "company": "Allogene Therapeutics, Inc.", "org_type": "公司", "target": "BCMA/CD70", "modality": "CAR", "importance_level": "高", "total_score": 82.5, "institution_score": 85, "track_score": 90, "milestone_score": 70, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "该药为Allogene开发的异体BCMA/CD70双靶点CAR-T，针对高危多发性骨髓瘤，可克服抗原逃逸和异体排斥。Allogene作为国外头部allogeneic CAR-T biotech公司，赛道热门（双靶点CAR-T+异体+抗原逃逸解决），preclinical数据强劲显示优于单靶点，综合潜力高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5195", "id": "ap7ECZ0BZznHJdntvNYd", "source_drug_name": "BCMA/CD70 Dual CAR T cells", "title": "Preclinical evaluation of allogeneic BCMA/CD70 Dual CAR T cells for high-risk multiple myeloma", "abstract_text": "Off-the-shelf allogeneic CAR T cells manufactured from healthy donor T cells could potentially address some of the limitations of autologous therapies by providing a more consistent product, immediate availability, and the convenience of scalable manufacturing. However, premature rejection of allogeneic CAR T cells may limit persistence and clinical responses. We previously reported the development of an anti-rejection CD70 CAR that can selectively eliminate CD70+ alloreactive T cells and overcome rejection. Notably, recent studies reported high CD70 expression in high-risk multiple myeloma (MM), supporting the evaluation of CD70-targeted therapies in this patient population.\nHere we evaluated the ability of allogeneic CAR T cells targeting BCMA and CD70 to overcome rejection and BCMA antigen loss in preclinical models of multiple myeloma. Human T cells were engineered with CRISPR gene-editing technology to knock out the TRAC locus and to allow site-specific integration (SSI) of a BCMA/CD70 Dual CAR construct. Following expansion, TRAC KO Dual CAR T cells were characterized by flow cytometry and through various in vitro assays including cytotoxicity, cytokine release, target-mediated expansion and mixed lymphocyte reactions (MLR). In vivo efficacy and expansion of Dual CAR T cells were evaluated in mice engrafted with MOLP-8 MM cells.\nAllogeneic BCMA/CD70 Dual CAR T cells produced from multiple donors exhibited high efficiency of TRAC KO (98-99%), sustained expression of the BCMA and CD70 CARs, and a balanced effector and memory phenotype. In MLR assays with previously-primed T cells, BCMA/CD70 Dual CAR T cells showed resistance to allorejection and expanded > 5-fold, whereas control cells not expressing the CD70 CAR were rapidly eliminated. In response to target cells, BCMA/CD70 Dual CAR T cells produced high levels of IFN gamma, TNF alpha, and IL-2, and exhibited sustained killing and expansion following repeated stimulation. In addition, BCMA/CD70 Dual CAR T cells displayed high efficacy and expansion in a xenograft model of multiple myeloma. Compared with single targeting BCMA CAR T cells, BCMA/CD70 Dual CAR T cells showed improved cytotoxic activity and expansion in an in vitro model of antigen-escape.\nTaken together, these results demonstrate that BCMA/CD70 Dual CAR T cells produced using site-specific integration show specific cytotoxic activity, rejection avoidance, and the ability to eliminate tumor cells that have downregulated BCMA. Our findings underscore the promise of allogeneic BCMA/CD70 Dual CAR T cells as an accessible, off-the-shelf treatment option for high-risk multiple myeloma patients and those who have progressed after BCMA-directed therapies, with the potential to extend beyond multiple myeloma toward broader applications in autoimmune disorders.", "source_company": "Allogene Therapeutics, Inc.", "source_org_type": "公司", "row_number": 839, "target_meta": "BCMA,CD70", "MOA_meta": "其他"}, {"drug_name": "a novel biparatopic antibody-drug conjugate (ADC) targeting delta-like ligand 3 (DLL3)", "company": "Earendil Labs", "org_type": "公司", "target": "DLL3", "modality": "ADC", "importance_level": "高", "total_score": 82.5, "institution_score": 85, "track_score": 90, "milestone_score": 70, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "靶点为DLL3的biparatopic ADC，采用AI优化双表位抗体提升内化效率和疗效，在SCLC等神经内分泌瘤中显示优于单抗ADC的preclinical活性。机构为快速融资近8亿美元、获Sanofi/Pfizer支持的头部AI驱动biotech，热门ADC+新兴DLL3赛道加AI亮点，总分高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4293", "id": "TlXM_5wBX1NQZOEH-LS6", "source_drug_name": "a novel biparatopic antibody-drug conjugate (ADC) targeting delta-like ligand 3 (DLL3)", "title": "An AI-guided biparatopic DLL3-targeting ADC demonstrates enhanced preclinical efficacy", "abstract_text": "Purpose This study aimed to develop a novel biparatopic antibody-drug conjugate (ADC) targeting delta-like ligand 3 (DLL3) for small cell lung cancer (SCLC) and other neuroendocrine neoplasms, addressing limitations of previous DLL3-targeted therapies.\nMethods Leveraging our AI-guided antibody development platform, we engineered a biparatopic anti-DLL3 antibody with optimized binding and internalization properties. The antibody was conjugated with various linker-payload combinations. In vitro cytotoxicity of the ADCs were evaluated using DLL3-expressing cell lines and in vivo efficacy were assessed using CDX mice models. Safety was assessed in transgenic mice and non-human primates.\nResults The biparatopic antibody demonstrated higher internalization efficiency compared to the monoclonal antibody counterparts. The ADC showed potent cytotoxicity across multiple DLL3-expressing cell lines and achieved significant tumor suppression in CDX models. Toxicological studies revealed a favorable safety profile in both transgenic mice and non-human primates.\nConclusion This biparatopic ADC represents a promising therapeutic candidate for DLL3-expressing tumors, demonstrating enhanced efficacy and favorable preclinical safety compared to previous approaches.", "source_company": "Earendil Labs", "source_org_type": "公司", "row_number": 887, "target_meta": "DLL3", "MOA_meta": "抗体偶联药物"}, {"drug_name": "BHB299", "company": "BigHat Biosciences, Inc.", "org_type": "公司", "target": "CEACAM6", "modality": "TCE", "importance_level": "高", "total_score": 82.5, "institution_score": 75, "track_score": 90, "milestone_score": 85, "field_heat_score": 85, "bonus_score": 8, "brief_reason": "BHB299为AI/ML优化的高亲和/低亲和CEACAM6定向T细胞衔接器（TCE），采用avidity-based机制实现肿瘤选择性并结合pH条件CD3激动，针对多种实体瘤；BigHat作为国外头部AI驱动biotech（获多家大药企合作、Fierce 15等认可），赛道热门（TCE+新兴靶点CEACAM6），preclinical数据强劲（多种模型完全缓解、无MTD、计划2026 FIH），综合热度高并有新机制亮点。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3631", "id": "oFXM_5wBX1NQZOEH-LK6", "source_drug_name": "BHB299", "title": "BHB299: An AI/ML-optimized high avidity/low affinity CEACAM6-directed T cell engager for diverse solid tumors", "abstract_text": "Background: Solid tumors remain a major cause of global mortality, with millions of new cases annually. Despite a rapidly advancing standard of care, few patients achieve durable responses. CEACAM6 is a cell surface antigen expressed at extremely high levels on CRC (>85%), NSCLC (>50%), Gastric (>30%), Pancreatic (>30%) and a variety of other tumor types where it drives tumor metastasis and immune suppression through heterotypic interactions with adjacent cancer and infiltrating immune cells. CEACAM6 has historically been considered undruggable due to its moderate expression on healthy myeloid cells, which act as a peripheral antigen sink and a source of on-target/off-tumor dose-limiting toxicity.\nMethods: A single domain VHH anti-CEACAM6 antibody was discovered and co-optimized alongside a CD3 binding domain for ultra-fast dissociation and developability using BigHat’s proprietary AI/ML and cell-free protein synthesis (CFPS)-enabled platform. Comprehensive in vitro and in vivo studies of PK, PD, and safety were performed to support the candidacy of BHB299 for first-in-human evaluation.\nResults: The resulting “2+1” T cell engager binds to cell surfaces with high CEACAM6 densities with high avidity and slow dissociation, but dissociates rapidly from myeloid cells with moderate target densities. This dynamic CD3 and CEACAM6 engagement selectively establishes an immunological synapse between tumor cells and T cells but not healthy myeloid cells, with >10,000x differential in IC50 in vitro using relevant models of cancer and whole blood from human donors. This avidity-based or “IF-BETTER” mechanism also eliminates sensitivity to soluble forms of CEACAM6, which may act as a decoy and antigen sink for high-affinity therapeutics. BHB299 also features a pH conditional CD3 agonist, which further enhances cell killing in the tumor microenvironment to reduce the risk of antigen escape due to low target expression. In vivo, BHB299 leads to complete responses or durable partial responses in multiple models of colon, rectal, lung, and pancreatic tumors, including metastatic PDX models of CRC and lung cancers. In safety studies in humanized mouse models and primates, no MTD was reached, consistent with a substantial therapeutic window.\nConclusion: BHB299 is a first-in-class CEACAM6-directed bispecific T cell engager for the treatment of diverse solid tumors, potentially up to 10% of all new cancers in the US each year. The molecule was engineered on BigHat Biosciences’s AI/ML-powered antibody design platform to maximise tumor-specific target engagement. First-in-human studies are supported by the preclinical data package and are planned for 2026.", "source_company": "BigHat Biosciences, Inc.", "source_org_type": "公司", "row_number": 1265, "target_meta": "CEACAM6", "MOA_meta": "其他"}, {"drug_name": "RCZY-698", "company": "Rongchang Pharmaceuticals, Ltd.", "org_type": "公司", "target": "KRASG12V (ON-state)", "modality": "inhibitor", "importance_level": "高", "total_score": 82.5, "institution_score": 75, "track_score": 95, "milestone_score": 75, "field_heat_score": 90, "bonus_score": 5, "brief_reason": "RCZY-698为口服、高效、选择性KRAS G12V(ON)态非共价三元复合物抑制剂，靶向GTP结合活性态并通过CypA形成三元复合物实现高选择性，在KRAS G12V肿瘤模型中显示强效肿瘤退缩。机构为国内有创新实力制药企业（非头部TOP但有生物药布局），KRAS G12V为高热度未满足需求靶点+热门小分子抑制剂赛道，preclinical数据强劲且优于竞品。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8726", "id": "JVXM_5wBX1NQZOEH-LO6", "source_drug_name": "RCZY-698", "title": "RCZY-698: An orally bioavailable, highly potent, and selective reversible KRASG12V (ON)-state inhibitor with robust antitumor activity in preclinical models of KRASG12V-driven solid tumors", "abstract_text": "The KRASG12V mutation is the second most common oncogenic RAS alteration, particularly as a driver mutation in pancreatic (~34%), colorectal (~21%), and non-small cell lung cancers (~5%). It is associated with poor prognosis in affected cancer patients. Due to its very low GTPase activity, which impairs hydrolysis of RAS-bound GTP to RAS-bound GDP, the mutant protein spends most of its time in the active (GTP-bound) state with limited cycling. As a result, an off-state KRASG12V inhibitor targeting the conformation of GDP-bound (inactive) state would theoretically be ineffective at blocking downstream signaling pathways such as MAPK and PI3K-AKT, as the mutant protein rarely accesses its GDP-bound state. The lack of a nucleophilic side chain at position 12 (valine) of KRASG12V precludes development of covalent inhibitors targeting the mutation site directly. Currently, no direct inhibitors targeting KRASG12V have been approved, representing a significant unmet medical need. RCZY-698, developed by Rongchang Pharmaceuticals, is a novel, highly potent, orally bioavailable, and mutant-selective non-covalent tri-complex inhibitor that specifically targets the GTP-bound (ON) conformation of KRASG12V. It potently disrupts the interaction between KRASG12V and downstream effector proteins, thereby robustly suppressing key signaling cascades, including the MAPK pathway mechanistically, RCZY-698 engages cyclophilin A (CypA) specifically to form a stable ternary complex with KRASG12V, conferring exceptional selectivity over wild-type KRAS. In a panel of KRASG12V-mutant tumor cell lines, RCZY-698 elicits potent antiproliferative effects, demonstrating superior in vitro growth inhibition compared with RMC-5127. This compound exhibits favorable in vitro absorption, distribution, metabolism, and excretion (ADME) characteristics, alongside distinctive oral pharmacokinetic profiles across multiple species. In human KRASG12V-mutant xenograft models, RCZY-698 induces dose-dependent tumor regression at well-tolerated doses, achieving comparable tumor growth inhibition (TGI) to RMC-5127 at substantially lower exposures. Collectively, these data delineate the discovery and preclinical profiling of RCZY-698 as a novel oral non-covalent KRASG12V(ON)-selective tri-complex inhibitor with compelling in vitro potency and in vivo efficacy. Further efforts and characterization work are being implemented to complete the preclinical candidate (PCC) data package for RCZY-698.", "source_company": "Rongchang Pharmaceuticals, Ltd.", "source_org_type": "公司", "row_number": 1285, "target_meta": "not available", "MOA_meta": "抑制剂"}, {"drug_name": "PK313", "company": "Aethon Therapeutics", "org_type": "公司", "target": "KRAS amplification (pMHC antigen kAMP.A2 / pKA-A2)", "modality": "bispecific antibody", "importance_level": "高", "total_score": 82, "institution_score": 75, "track_score": 90, "milestone_score": 80, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "PK313为TCR-mimicking bispecific TCE，靶向KRAS扩增肿瘤特异性pMHC抗原，可克服KRAS抑制剂耐药。Aethon为国外头部VC支持的创新biotech，赛道热门（TCE+KRAS相关），preclinical数据强（高亲和力、特异性、EC50 picomolar级），组合潜力大。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5515", "id": "ilXM_5wBX1NQZOEH-LK6", "source_drug_name": "PK313", "title": "KRAS amplification creates a targetable pMHC antigen for T cell engager therapy to overcome KRAS inhibitor resistance", "abstract_text": "KRAS amplification has emerged as a shared mechanism of resistance to KRAS-targeted therapies, including KRASG12C and KRAS-multi small molecule inhibitors. Wild-type KRAS allele amplification also defines a subset of aggressive gastroesophageal cancers with poor outcomes. To exploit this alteration, we sought a mutation-agnostic, HLA-A*02:01-restricted KRAS pMHC antigen selectively presented in KRAS-amplified tumors. Using peptide prediction & targeted immunopeptidomics, we identified the amplified antigen “kAMP.A2,” enabling a strategy to selectively target KRAS-amplified tumors with a bispecific pMHC×CD3 T cell engager (TCE). Quantitative immunopeptidomics across multiple models estimated kAMP.A2 at ~102-103 copies-per-cell (CPC) in KRAS-amplified cell lines (MKN1*, 119 CPC; COR-L23*, 555; HSKTC*, 1432) and undetectable or <10 CPC in non-amplified cell lines (A375, NCI-H661, ND; NCI-H520*, 9). A*02:01-negative lines (*) were A*02:01-engineered. KRAS pathway inhibition further increased antigen levels: treatment of 10 nM RMC-7977 in COR-L23 cells (G12V; KRAS CN=16), produced a 2.5× rise in surface HLA and an 8-fold increase in kAMP.A2, reaching ~4,000 CPC at 48 h. KRAS amplification thereby establishes an exploitable pMHC therapeutic window—analogous to gp100 or PRAME—that is further broadened by KRAS inhibition. Importantly, NRAS & HRAS paralogs of kAMP.A2 were not detected in any model. Consistent with this, stability profiling showed kAMP.A2 to be markedly more stable at 37 °C (t½ ≈ 45 min) than NRAS/HRAS peptides (t½ < 4 min), supporting kAMP.A2 as a selective TCE target with minimal paralog cross-reactivity. Screening our ultra-large human naïve antibody library with phage/yeast display and stringent counter-selection yielded the TCR-mimicking antibody PK313, exhibiting high affinity (KD = 5.3 nM) and strict specificity confirmed by SPR as well as by X-scan and healthy-tissue pMHC libraries (>102 & ~104 peptides) with no high-affinity off-targets. A 2.8-Å cryo-EM structure revealed extensive kAMP.A2-specific contacts. Reformatted as a TCE, PK313 induced potent cytotoxicity in KRAS-amplified models (MKN1*, EC50 = 1.1 nM; COR-L23*, 150 pM; HSKTC*, 160 pM) and showed enhanced activity with KRAS inhibitors. Structure-guided maturation is underway to advance PK313 toward development candidate nomination. Our data demonstrate that KRAS amplification—whether intrinsic or emerging under therapeutic pressure—creates a robust, tumor-amplified pMHC antigen with exceptional potential for therapeutic exploitation. PK313 enables selective targeting of KRAS-amplified tumors as a monotherapy or in combination with KRAS small molecule inhibitors to enhance treatment durability and provides a therapeutic strategy for A*02:01 patients (~42% in US population), who are currently excluded from A*03/A*11 KRAS-mutant neoantigen TCR-T/CAR-T/TCE programs.", "source_company": "Aethon Therapeutics", "source_org_type": "公司", "row_number": 216, "target_meta": "KRAS", "MOA_meta": "双特异性抗体"}, {"drug_name": "HY809382", "company": "Yangtze River Pharmaceutical (Group) Co., Ltd.", "org_type": "公司", "target": "EED", "modality": "degrader", "importance_level": "高", "total_score": 82, "institution_score": 85, "track_score": 85, "milestone_score": 75, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "HY809382为靶向EED的PRC2 degrader，可克服EZH2抑制剂因突变导致的耐药，在前列腺癌、子宫内膜癌、胃腺癌等多种肿瘤模型中显示优于EZH2/EED抑制剂的活性并具协同潜力。长江医药作为中国头部制药企业（曾多年位列国内药企榜首），赛道为热门表观遗传degrader，preclinical数据扎实且具best-in-class特性，故综合评分较高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8736", "id": "gp7M_5wBZznHJdnt_W3O", "source_drug_name": "HY809382", "title": "HY809382, a PRC2 degrader with best-in-class properties, demonstrates efficacy across multiple tumors and overcomes EZH2 inhibitor clinical resistance caused by EZH2 genetic mutations", "abstract_text": "The dysregulation of Polycomb repressive complex 2 (PRC2) is implicated in tumorigenesis across a spectrum of cancers, such as prostate cancer, non-small cell lung cancer, ​endometrial carcinoma, ovarian cancer, clear cell renal cell carcinoma and hematological malignancies. Furthermore, aberrant PRC2 activity is closely associated with tumor immune evasion and the development of therapy resistance, thereby influencing clinical outcomes. Given its critical role in tumor initiation and progression, the core PRC2 subunits EZH2 and EED have emerged as promising therapeutic targets. Among various EZH2 inhibitors under development, Tazemetostat (Tazverik) was the first to received FDA approval for the treatment of follicular lymphoma (FL) and epithelioid sarcoma (ES). Despite this progress, new challenges have emerged, including acquired resistance through EZH2 mutations and limited efficacy in tumors due to EZH1 compensatory mechanisms. Degradation of EED disrupts the assembly, stability, and activity of PRC2 complex, offering potential advantages over merely inhibiting EZH2 catalytic function. HY809382 is a potent and selective PRC2 degrader that targeted the EED subunit, designed with superior drug-like properties compared to existing EZH2 and EED inhibitors. HY809382 potently inhibited the proliferation of multiple tumor cell lines in vitro, including prostate cancer, endometrial carcinoma and gastric adenocarcinoma. Under identical experimental conditions, HY809382 exhibited greater potency than both PF-06821497 (an EZH2 inhibitor) and APG-5918 (an EED inhibitor). Once-daily oral administration of HY809382 demonstrated significant and dose-dependent tumor growth inhibition in xenograft models of prostate cancer, endometrial carcinoma, and gastric adenocarcinoma. Furthermore, HY809382 combined with enzalutamide synergistically suppressed tumor growth in a castration-resistant prostate cancer xenograft model. Clinically identified EZH2 mutations confer resistance to FDA-approved EZH2 inhibitors, whereas HY809382 remained effective in both cellular and in vivo xenograft models. Collectively, these data support HY809382 as a promising best-in-class PRC2 degrader candidate, warranting further development for the treatment of tumors exhibiting clinical resistance to EZH2 inhibitors.", "source_company": "Yangtze River Pharmaceutical (Group) Co., Ltd.", "source_org_type": "公司", "row_number": 269, "target_meta": "EED", "MOA_meta": "降解剂"}, {"drug_name": "Antares’s p53 Y220C reactivators", "company": "Antares Therapeutics", "org_type": "公司", "target": "p53 Y220C", "modality": "inhibitor", "importance_level": "高", "total_score": 82, "institution_score": 85, "track_score": 85, "milestone_score": 75, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "靶向p53 Y220C突变的重激活剂，较rezatapopt体外和体内 potency显著提升≥10倍，尤其在KRAS突变模型中表现优异。Antares作为Scorpion Therapeutics spin-out、获1.77亿美元A轮融资的头部新兴biotech，处于热门肿瘤抑制基因恢复赛道且有best-in-class潜力。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8859", "id": "-FXM_5wBX1NQZOEH-LC5", "source_drug_name": "Antares’s p53 Y220C reactivators", "title": "Highly potent and mutant-selective p53 Y220C reactivators with best-in-class potential", "abstract_text": "Background: The tumor suppressor p53, encoded by the TP53 gene, is a transcription factor that regulates genes involved in DNA repair, cell cycle arrest, senescence, and apoptosis. TP53 is the most frequently altered tumor suppressor gene with mutations occurring in over 50% of human cancers. TP53 mutations result in a loss of function, rendering cells incapable of responding to a variety of cellular stresses, making them susceptible to tumorigenesis. The Y220C hotspot mutation accounts for 1.8% of all p53 mutations, occurring in ~1% of all solid tumors. p53 Y220C is a structural mutation that causes destabilization of the p53 protein. Small molecules that bind to a pocket formed by the Y220C mutation, but absent in the p53 wild-type protein, can stabilize the protein to restore normal function. Rezatapopt (PC14586) is the first p53 Y220C reactivator to enter clinical trials, where it is showing clinical benefit. However, because this molecule has modest potency, its efficacy may be limited by insufficient p53 reactivation despite a high RP2D (2000 mg QD), particularly in KRAS mutant patients.\nMaterials and Methods: Antares’s p53 Y220C reactivators were evaluated biochemically in SPR binding and thermal shift assays. Cellular activity was assessed in target engagement, target gene expression and cell proliferation assays across a panel of p53 Y220C mutant cell lines. Additionally, chromatin binding and target gene expression conferred by p53 Y220C reactivation were analyzed by ChIP-seq and RNA-seq. Finally, the in vivo efficacy was studied in several human CDX and PDX p53 Y220C models.\nResults: Antares’s orally bioavailable p53 Y220C reactivators demonstrated a ≥10-fold improvement in in vitro potency over rezatapopt in target engagement, ChIP-seq and RNA-seq assays, with corresponding potency improvements in cell proliferation assays across a panel of p53 Y220C mutant cell lines. In vivo, these compounds were effective in inhibiting tumor growth in multiple p53 Y220C CDX models at a significantly lower dose than rezatapopt. Importantly, these p53 reactivators exhibit a marked improvement in activity in a KRAS mutant model, both in vitro and in vivo.\nConclusions: The significantly improved potency of the novel p53 reactivators described here offers the opportunity to restore p53 function in less sensitive patient populations and meaningfully improve upon the clinical response profile of rezatapopt.", "source_company": "Antares Therapeutics", "source_org_type": "公司", "row_number": 302, "target_meta": "p53 Y220C", "MOA_meta": "抑制剂"}, {"drug_name": "YL252", "company": "MediLink Therapeutics (Suzhou) Co., Ltd.", "org_type": "公司", "target": "PD-L1/VEGF", "modality": "ADC", "importance_level": "高", "total_score": 81.5, "institution_score": 75, "track_score": 95, "milestone_score": 70, "field_heat_score": 90, "bonus_score": 8, "brief_reason": "YL252为双功能ADC同时靶向PD-L1和VEGF，实现免疫治疗+抗血管生成+细胞毒三合一机制；宜联生物作为国内ADC领域头部biotech，已有多款ADC临床并获国际大药企合作，高赛道热度+良好非临床数据（完全缓解、无明显毒性、高治疗指数）支撑高分。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5454", "id": "UZ7M_5wBZznHJdnt_W7P", "source_drug_name": "YL252", "title": "YL252: A dual-functional PD-L1/VEGF-targeting ADC integrating immunotherapy, anti-angiogenesis, and cytotoxicity", "abstract_text": "The clinical success of combining immune checkpoint inhibitors with antibody-drug conjugates (ADCs), as well as the well-established synergy among immunotherapy, anti-angiogenic therapy, and chemotherapy, supports the development of multi-mechanistic therapeutic strategies. Based on this rationale, we developed YL252, a dual-functional ADC designed to simultaneously target PD-L1 and VEGF while enabling controlled payload release within the tumor microenvironment. YL252 is derived from Tumor Microenvironment-Activable Linker platform, incorporating a proprietary protease-cleavable tripeptide linker and a novel DNA topoisomerase I inhibitor payload. YL252 binds PD-L1 to modulate immune suppression, while also sequestering soluble VEGF, thereby exerting anti-angiogenic effects. The engineered drug-to-antibody ratio (DAR) is optimized to align with clinically relevant exposures of anti-PD-L1 and anti-VEGF monoclonal antibodies. We conducted a comprehensive nonclinical evaluation of YL252, including assessments of physicochemical properties, antitumor efficacy, pharmacokinetics, and safety. YL252 showed efficient internalization, potent cytotoxicity, and strong bystander effects in PD-L1-expressing tumor cells. In xenograft models, YL252 produced dose-dependent tumor growth inhibition, including complete regressions, without detectable toxicity. Mechanistic studies confirmed that YL252 effectively blocked PD-L1 signaling, consistent with immune activation alongside cytotoxic and antiangiogenic activity. Pharmacokinetic studies in cynomolgus monkeys demonstrated high systemic stability, as shown by overlapping total antibody and conjugated ADC profiles. Repeat-dose toxicology studies established a favorable safety profile, with a therapeutic index of approximately 100 and no drug-related adverse findings in major organs, including lung, liver, and kidney. In summary, YL252 is the first reported ADC that concurrently blocks PD-L1, inhibits VEGF-driven angiogenesis, and releases a cytotoxic payload in the tumor microenvironment, representing a single-agent approach that integrates immunotherapy, anti-angiogenic therapy, and chemotherapy mechanisms.", "source_company": "MediLink Therapeutics (Suzhou) Co., Ltd.", "source_org_type": "公司", "row_number": 112, "target_meta": "PDL1", "MOA_meta": "抗体偶联药物"}, {"drug_name": "QLS2401", "company": "Shanghai Qilu Pharmaceutical Research and Development Center LTD.", "org_type": "公司", "target": "PSMA/STEAP1/CD3", "modality": "TCE", "importance_level": "高", "total_score": 81.5, "institution_score": 75, "track_score": 90, "milestone_score": 80, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "QLS2401为新型PSMA/STEAP1/CD3三特异性T细胞衔接器（TCE），针对mCRPC双靶点设计以克服单靶点丢失耐药。齐鲁制药作为国内TOP pharma，赛道热门（三特异性TCE+前列腺癌热门靶点），猴毒性研究显示更宽治疗窗和优于xaluritamig类似物的疗效与耐受性，preclinical强度高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5735", "id": "JZ7M_5wBZznHJdnt_W7O", "source_drug_name": "QLS2401", "title": "QLS2401: A novel PSMA/STEAP1/CD3 tri-specific T-cell engager for the treatment of mCRPC", "abstract_text": "Prostate cancer (PCa) is one of the most common malignancies in men worldwide. Approximately 10%-20% of PCa patients develop castration-resistant PCa (CRPC) within 5 years and subsequently progress to metastatic CRPC (mCRPC). Current approved therapies for mCRPC patients offer limited survival benefits with unsatisfied long-term remission, underscoring an urgent need for novel therapeutic options. Both STEAP1 (Six Transmembrane Epithelial Antigens of the Prostate 1) and PSMA (Prostate-Specific Membrane Antigen) are frequently co-expressed at high levels in mCRPC, presenting dual targeting opportunity to enhance efficacy. Here, we report the generation and preclinical development of QLS2401, a novel PSMA/STEAP1/CD3 tri-specific TCE engineered to have optimized CD3 affinity and tumor associated antigen (TAA)-binding valency to enhance T cell-mediated cytotoxicity and mitigate the resistance resulting from single antigen-loss. QLS2401 causes potent target-dependent and T cell-mediated cytotoxicity against prostate cancer cell lines and induces tumor regression in prostate cancer xenograft models, demonstrating superior or comparable efficacy to the xaluritamig analog. The avidity-driven activity of QLS2401 enables selectivity for tumor cells with higher STEAP1- and PSMA- expression than normal cells. QLS2401 was well-tolerated in a toxicity study in cynomolgus monkeys, with an HNSTD (Highest Non-Severely Toxic Dose) significantly higher than that of the xaluritamig analog. In conclusion, preclinical studies have demonstrated that QLS2401 exhibits an expanded therapeutic window, superior efficacy and improved tolerability compared to the xaluritamig analog.", "source_company": "Shanghai Qilu Pharmaceutical Research and Development Center LTD.", "source_org_type": "公司", "row_number": 117, "target_meta": "PSMA,STEAP1,CD3", "MOA_meta": "其他"}, {"drug_name": "Sutro’s HER2-targeting dpADC", "company": "Sutro Biopharma", "org_type": "公司", "target": "HER2", "modality": "dpADC", "importance_level": "高", "total_score": 81.5, "institution_score": 75, "track_score": 95, "milestone_score": 70, "field_heat_score": 85, "bonus_score": 8, "brief_reason": "HER2靶向双负载ADC（dpADC）结合TOPO1i和MTi双机制，克服单负载ADC耐药，preclinical显示优于Enhertu的抗瘤活性及耐药模型中深层持久响应。Sutro作为专注ADC的国外biotech，dpADC为热门赛道创新，preclinical强度强且有清晰克服耐药价值，综合热度高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5357", "id": "V1XM_5wBX1NQZOEH-LK6", "source_drug_name": "Sutro’s HER2-targeting dpADC", "title": "The HER2-targeting dual-payload antibody-drug conjugate combining a topoisomerase I inhibitor and a microtubule inhibitor demonstrates superior efficacy and overcomes resistance to single-payload ADCs in xenograft models", "abstract_text": "The genetic and phenotypic heterogeneity of human cancers is a primary driver of drug resistance, posing a major challenge to achieving durable therapeutic responses. To overcome this, Sutro has developed a dual-payload antibody-drug conjugate (dpADC) platform that enables precise co-delivery of two cytotoxic payloads via a single, homogeneous molecule. Sutro’s HER2-targeting dpADC demonstrates that simultaneous delivery of two cytotoxic payloads provides greater anti-tumor activity than single-payload ADCs and overcomes preclinical, in-vivo-derived treatment resistance. Combining Sutro Biopharma’s XpressCF+® cell-free expression system with site-specific conjugation technology, we engineered a HER2-targeting dpADC combining exatecan (topoisomerase I inhibitor; TOPO1i) and monomethyl auristatin E (MMAE) (microtubule inhibitor; MTi) payloads at an 8:4 ratio. The resulting dpADC exhibited favorable pharmacokinetics in vivo and minimal linker-payload loss over a 21-day study. In in vitro cell killing assays, the dpADC performed better than Enhertu and DAR8 exatecan ADC across multiple tumor cell lines. In in vivo efficacy studies, the dpADC exhibited greater anti-tumor activity than both single-payload ADC comparators across multiple xenograft models. To further evaluate the dpADC concept’s potential, we examined its utility in addressing resistance induced by ADC treatment. To mimic resistances to single payload ADCs observed in the clinic, we continuously dosed xenograft tumors with Enhertu on a weekly dosing schedule until the tumors progressed. These Enhertu-resistant tumors were then continuously dosed with a MTi ADC until de novo resistance developed. Dual-resistant tumors were then treated with a dpADC resulting in deep and durable anti-tumor responses. Even in tumors that were rendered resistant to both payloads, the dpADC treatment was able to achieve substantial tumor regression, demonstrating the potential for benefit in mono payload ADC refractory settings. Overall, these results indicate that Sutro’s HER2 dpADC can enhance anti-tumor activity beyond that of single-payload ADCs and can overcome prior treatment-induced resistance in a preclinical setting.", "source_company": "Sutro Biopharma", "source_org_type": "公司", "row_number": 215, "target_meta": "HER2", "MOA_meta": "抗体偶联药物"}, {"drug_name": "GR9001/GQ9001", "company": "GeneQuantum Healthcare (Suzhou) Co., Ltd.", "org_type": "公司", "target": "PSMA", "modality": "RLT imaging agent", "importance_level": "高", "total_score": 81.5, "institution_score": 75, "track_score": 85, "milestone_score": 85, "field_heat_score": 90, "bonus_score": 5, "brief_reason": "基于纳米抗体靶向PSMA的放射性药物偶联物（RDC），采用⁶⁴Cu/¹⁷⁷Lu标记，在临床前及首个人体研究中显示优于Pluvicto®的肿瘤摄取、保留、安全性和疗效。GeneQuantum作为国内专注生物偶联平台的创新biotech公司，赛道热门且有临床数据支撑，综合潜力突出。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3901", "id": "Ip7M_5wBZznHJdnt_W7O", "source_drug_name": "GR9001/GQ9001", "title": "Synergistic integration of nanobodies and a specialized linker library: A novel radionuclide drug conjugate (RDC) platform paving the way for next-generation radiotherapeutics with optimal druggability and therapeutic index", "abstract_text": "Background: Radionuclide drug conjugates (RDCs) represent a promising approach in oncology, yet their development is hindered by the scarcity of targeting moieties possessing both high affinity and favorable pharmacokinetics, leading to intense competition for validated targets. To address this, we have developed a novel and differentiated RDC platform utilizing readily available nanobodies as targeting vectors. This platform incorporates our intelligent Ligase-Dependent Conjugation (iLDC) technology and a proprietary linker, which collectively enhance pharmacokinetic profiles and biodistribution. The platform's efficacy is validated by GR9001, a ⁶⁴Cu/¹⁷⁷Lu-labeled anti-PSMA nanobody-based RDC, which has demonstrated superior tumor targeting and biodistribution, potent therapeutic efficacy, and a promising safety profile in both preclinical and first-in-human studies.\nResults: In preclinical studies, 64Cu-GQ9001 exhibits an enhanced pharmacokinetic profile, along with excellent biodistribution characterized by significantly higher tumor accumulation and retention and minimized kidney uptake. Meanwhile, 177Lu-GQ9001 also demonstrates superior antitumor activity and shows great potential to overcome resistance to Pluvicto®. In mCRPC patients, 177Lu-GQ9001 was well tolerated, and no severe adverse events were observed. SPECT images revealed an optimal circulation half-life of 177Lu-GQ9001 in the blood, with high, increasing tumor uptake and low, rapidly clearing normal tissue uptake. Compared with published data for other PSMA-targeted radioligands (e.g., PSMA-617), 177Lu-GQ9001 exhibited significantly higher normalized absorbed doses in tumor lesions and similar absorbed doses in normal organs. Consequently, this profile resulted in substantially superior tumor-to-background (T/B) ratios. Furthermore, 177Lu-GQ9001 showed superior efficacy at lower doses, with a significant reduction in PSA levels.\nConclusion: By leveraging GQ’s nanobody-based RDC platform, a potential best-in-class anti-PSMA RDC has been developed that demonstrates a comprehensively superior profile to Pluvicto®—including optimized half-life, enhanced tumor uptake, excellent safety, and potent efficacy in CDX models and mCRPC patients—thereby establishing a transformative paradigm that expands the promise of nanobody-based therapeutics beyond existing modalities to novel tumor targets.", "source_company": "GeneQuantum Healthcare (Suzhou) Co., Ltd.", "source_org_type": "公司", "row_number": 277, "target_meta": "PSMA", "MOA_meta": "其他"}, {"drug_name": "PA289", "company": "Iksuda Therapeutics Limited", "org_type": "公司", "target": "未披露", "modality": "ADC", "importance_level": "高", "total_score": 81.5, "institution_score": 75, "track_score": 90, "milestone_score": 75, "field_heat_score": 85, "bonus_score": 8, "brief_reason": "PA289为新型seco-CBI类prodrug payload，独特蛋白烷化（ProAlk）机制，通过ADC形式实现肿瘤选择性激活。Iksuda作为专注ADC的国外头部biotech（获韩国LigaChem战略控股并持续推进临床），热门ADC+新型payload赛道，preclinical显示优于deruxtecan基准的效力和耐受性及耐药模型活性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5382", "id": "nlXM_5wBX1NQZOEH-LS6", "source_drug_name": "PA289", "title": "PA289: A first-in-class prodrug payload with a novel mechanism of action and favorable efficacy/safety profile", "abstract_text": "Background: PA289 is a novel seco-CBI based linker-payload with a differentiated protein alkylation (ProAlk) mechanism of action, killing cells via alkylation of cytosolic proteins​ (Wirth et al, 2012). It uses IKSUDA’s stable, cysteine-specific PermaLink conjugation technology and glucuronide triggers to enhance tolerability. Tumor overexpressed lysosomal glucuronidase leads to selective activation after ADC uptake and limits systemic release of the active payload. PA289’s unique MOA and prodrug format lead to controlled activation support improved therapeutic performance and help address the clinical challenge of ADC sequencing.\nMethods: The prodrug linker-payload PA289 was conjugated using PermaLink technology to generate ADCs with a drug to antibody ratio of approximately 4. In vitro cell-killing and bystander activity was evaluated by CellTiter-Glo assay and impact on cell cycle was determined by propidium iodide staining. An HMGB1 ELISA was used to monitor immunogenic cell death. Induction of apoptosis was measured by Caspase-Glo® 3/7 assay. Efficacy studies were conducted in immunodeficient mice engrafted with human cancer xenografts. Toxicology studies were conducted in cynomolgus monkeys.\nResults: The free payload shows potent in vitro activity against 248 cancer cell lines from 15 solid cancer indications (IC50 from 1-100 pM). Both the free payload and a PA289 ADC induce S-phase cell cycle arrest and apoptosis in vitro. The payload triggers immunogenic cell death and, unlike MMAE or deruxtecan, is a poor substrate for ABCB1 and ABCG2 drug efflux pumps. A PA289 ADC demonstrates stronger bystander cell-killing than an MMAE-ADC in co-cultures in vitro. Both the payload and a PA289 ADC retain activity against a trastuzumab deruxtecan-resistant cell line in vitro. This latter finding was confirmed in vivo, where a PA289 ADC shows durable tumor regressions in a trastuzumab deruxtecan-resistant xenograft. PA289 ADCs against multiple targets are active in vivo across several lung, esophageal and breast cancer xenograft models with a single dose of 0.3 mg/kg and show 10 to 20-fold greater potency than clinical benchmark ADCs with topoisomerase I inhibitor payloads. Despite this high in vivo potency, a PA289 ADC was well-tolerated in cynomolgus monkeys at 8 mg/kg (single dose) and 5 mg/kg repeat dose (Q3Wx2), with minimal test-article related findings.\nConclusions: PA289 is an ADC linker-payload with a unique protein alkylation mechanism and a novel glucuronide prodrug design, showing strong in vitro potency and low susceptibility to drug efflux pumps. PA289-based ADCs demonstrate superior in vivo activity compared with deruxtecan ADCs across multiple tumor models, with excellent tolerability in monkeys at doses well above those required for durable tumor regressions.", "source_company": "Iksuda Therapeutics Limited", "source_org_type": "公司", "row_number": 282, "target_meta": "not available", "MOA_meta": "抗体偶联药物"}, {"drug_name": "iGPS particle", "company": "Kelonia Therapeutics", "org_type": "公司", "target": "BCMA/CD19", "modality": "other", "importance_level": "高", "total_score": 81.5, "institution_score": 75, "track_score": 90, "milestone_score": 80, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "iGPS particle为体内基因递送系统，递送tandem anti-BCMA/CD19 CAR实现体内生成双靶点CAR-T细胞，靶向BCMA和CD19以清除CD19+和CD19-致病B细胞。Kelonia作为国外头部biotech，in vivo CAR-T赛道极热且具颠覆性，preclinical展示强效清除SLE B细胞和肿瘤控制，已推进至临床阶段，综合潜力高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5207", "id": "cVXM_5wBX1NQZOEH-LK6", "source_drug_name": "iGPS particle", "title": "Toward an in vivo anti-BCMA/CD19 CAR-T cell treatment of B cell-mediated autoimmune diseases", "abstract_text": "B cell-mediated autoimmune disorders, including systemic lupus erythematosus (SLE), can represent lifelong inflammatory conditions with limited therapeutic options. Autologous CD19-specific CAR-T cells have been demonstrated as an effective treatment option. However, access to CAR-T cell therapies and the use of preparative chemotherapy will ultimately limit the reach of this powerful modality. Moreover, recent data suggest that CD19-negative pathogenic plasma cells can emerge and contribute to SLE disease etiology, suggesting that development of CAR-T cells addressing both CD19-positive and CD19-negative pathogenic B cells is warranted. Here, we describe the preclinical development of an engineered lentiviral vector (LVV) previously shown to specifically modify T cells in vivo (in vivo gene placement system (iGPS®)), encoding a chimeric antigen receptor (CAR) that recognizes both CD19 and B-cell maturation antigen (BCMA) antigens (“tandem CAR”). The operative arms of the tandem CAR were identified by screening a panel of human anti-BCMA and anti-CD19 antibodies incorporating a variety of design features. Candidate tandem CAR constructs were expressed in T cells from healthy donors and SLE patients using iGPS particles. The constructs that caused antigen-specific in vitro T cell activity, assayed by cytotoxicity and cytokine release to cell lines expressing BCMA and/or CD19, were tested in several animal models. First, an SLE mouse model was established using immunocompromised mice humanized with peripheral blood mononuclear cells from SLE patients. After a single dose of the lead tandem CAR iGPS particle, CAR-T cells were generated and expanded in vivo resulting in complete elimination of SLE B cells in the blood, spleen, and bone marrow. In a second mouse model treating an aggressive B cell lymphoma, the iGPS particle delivering the lead tandem CAR caused effective tumor control after a single treatment. These data demonstrated the potential of a tandem anti-BCMA/CD19 CAR-T cell generated in vivo with iGPS particles as an effective treatment of autoimmune disorders. Moreover, persistent CAR-T cells generated using an LVV may provide a single, off-the-shelf treatment capable of eliminating both pathogenic CD19-positive B cells and emergent CD19-negative plasma cells and provide a needed therapy for patients.", "source_company": "Kelonia Therapeutics", "source_org_type": "公司", "row_number": 559, "target_meta": "BCMA,CD19", "MOA_meta": "其他"}, {"drug_name": "αPD-1/αVEGF/IL-21v", "company": "Mustbio", "org_type": "公司", "target": "PD-1, VEGF, IL-21 receptor", "modality": "tri-specific fusion protein", "importance_level": "高", "total_score": 81.5, "institution_score": 75, "track_score": 92, "milestone_score": 70, "field_heat_score": 90, "bonus_score": 5, "brief_reason": "该三特异性融合蛋白靶向PD-1、VEGF并通过TME选择性IL-21v激活增强CD8+ T细胞效应和记忆功能，超越PD-1/VEGF双特异性疗法，在ICI耐药模型中显示优异抗瘤效能和持久免疫记忆。Mustbio作为专注多特异性抗体平台的韩国新兴biotech，融资活跃并与Celltrion合作，赛道为热门多特异性免疫治疗+热门PD-1/VEGF/细胞因子组合，preclinical数据强劲具FIC/BIC潜力。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4557", "id": "HFXM_5wBX1NQZOEH-LO6", "source_drug_name": "αPD-1/αVEGF/IL-21v", "title": "A novel αPD-1/αVEGF/IL-21v tri-specific fusion protein exhibits potent antitumor efficacy beyond αPD-1/αVEGF bispecific therapy", "abstract_text": "Immune checkpoint inhibitors (ICIs) have been widely used for multiple malignancies. Nevertheless, response rates to ICIs remain limited across several tumor types, largely due to insufficient T cell infiltration and the inability to sustain long-term antitumor immunity within the tumor microenvironment (TME). Combinations of αPD-1 with αVEGF monoclonal antibodies (mAbs) or αPD-1/αVEGF bispecific antibodies (bsAbs) have demonstrated improved efficacy relative to αPD-1 monotherapy across multiple cancers. Despite such advances, strategies that not only enhance effector T cell accumulation within the TME but also promote sustained antitumor immune responses are essential to achieve therapeutic benefit in ICI-resistant or -refractory settings. Interleukin-21 (IL-21) enhances CD8+ T cell activation and memory T cell differentiation while limiting Treg expansion, supporting durable antitumor immunity. However, its broad off-target activity and short half-life limit clinical utility, motivating the development of TME-selective IL-21 variants (IL-21v). αPD-1/αVEGF/IL-21v is a tri-specific fusion protein comprising anti-PD-1, anti-VEGF, and an IL-21v engineered to minimize peripheral toxicity while sustaining T cell activation within the TME. This construct was designed to sustain T cell activation via αPD-1, enhance tumor-infiltrating lymphocytes (TILs) via αVEGF, and promote effector/memory T cells via IL-21v. The αPD-1/αVEGF/IL-21v exhibited PD-1/PD-L1 blocking activity comparable to pembrolizumab and VEGF/VEGFR blockade similar to bevacizumab. In PD-1⁺/PD-1⁻ HuT78 cells, it induced PD-1-dependent STAT3 activation with ~5,000-fold selectivity for PD-1⁺ cells. Consistently, PD-1high T cells treated with αPD-1/αVEGF/IL-21v secreted markedly higher IFN-γ and granzyme B than with αPD-1/αVEGF. Moreover, αPD-1/αVEGF/IL-21v promoted proliferation of CD8+IFN-γ+Granzyme B+ effector T cells and improved CD8⁺T/Treg ratio under in vitro TME-mimicking conditions, whereas αPD-1/αVEGF did not produce these effects. Importantly, under resting, peripheral-mimicking conditions, αPD-1/αVEGF/IL-21v induced minimal immune cell proliferation and low cytokine release. In ICI-resistant MC38 tumor model, αPD-1/αVEGF/IL-21v demonstrated superior antitumor efficacy compared with αPD-1 or αPD-1/αVEGF treatment, without adverse effects. Animals achieving complete responses did not relapse upon tumor re-challenge. This long-lasting efficacy was associated with an increased intratumoral CD8+T/Treg ratio and expansion of memory T cell populations within tumors rather than in peripheral blood. In conclusion, αPD-1/αVEGF/IL-21v is a novel TME-selective tri-specific fusion protein that enhances TIL recruitment and amplifies effector/memory T cell populations, offering therapeutic potential beyond αPD-1 or αPD-1/αVEGF therapy.", "source_company": "Mustbio", "source_org_type": "公司", "row_number": 669, "target_meta": "PD1,IL-21R", "MOA_meta": "融合蛋白"}, {"drug_name": "PROTACs", "company": "X-Chem, Inc.", "org_type": "公司", "target": "WDR5", "modality": "PROTAC", "importance_level": "高", "total_score": 81.5, "institution_score": 75, "track_score": 95, "milestone_score": 70, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "基于DEL技术发现新型E3连接酶配体DCAF1，并应用于靶向WDR5降解的PROTAC，为癌症治疗提供新E3配体扩展，机制创新性强。X-Chem作为国外头部DEL技术biotech平台，PROTAC+新型E3+难靶点WDR5赛道热度高，preclinical案例展示清晰价值。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6501", "id": "w57M_5wBZznHJdnt_W3O", "source_drug_name": "PROTACs", "title": "DEL-chemomics approach for the discovery of targeted protein degraders for cancer therapy", "abstract_text": "DNA-encoded chemical library (DEL) technology has become a powerful tool for hit identification, enabling the efficient screening of large collections of encoded compounds with advantages over traditional high-throughput screening in terms of library size, cost, and resource efficiency. The high chemical diversity and encoding fidelity of DELs yields extensive data that can support computational approaches such as machine learning (ML), 3D pharmacophore generation and structure-based discovery. This DEL-chemomics approach has been applied to the discovery of novel E3 ligase receptor ligands, expanding the repertoire of E3 ligands beyond the traditional CRBN and VHL for degradation of drug targets. A case study of the discovery of DCAF1 ligand and its application in PROTACs that targeted WDR5 for degradation will be presented.", "source_company": "X-Chem, Inc.\nX-Chem Pharmaceuticals", "source_org_type": "公司", "row_number": 1090, "target_meta": "WDR5", "MOA_meta": "PROTAC"}, {"drug_name": "GlycoConnect© dpADC", "company": "Synaffix – A Lonza Company", "org_type": "公司", "target": "未披露", "modality": "ADC", "importance_level": "高", "total_score": 81.5, "institution_score": 85, "track_score": 90, "milestone_score": 65, "field_heat_score": 85, "bonus_score": 3, "brief_reason": "GlycoConnect技术扩展至双负载ADC（dpADC），通过不同MoA负载组合应对肿瘤异质性和耐药，属于ADC领域热门创新方向；Lonza旗下Synaffix作为ADC技术领先平台提供商（多款伙伴ADC已临床甚至Phase 3），但本项仍为preclinical工具箱扩展，in vitro/in vivo数据展示潜力。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5371", "id": "ap7M_5wBZznHJdnt_W7P", "source_drug_name": "GlycoConnect© dpADC", "title": "GlycoConnect© ADC toolbox expansion with dual payload ADC (dpADC) technology", "abstract_text": "Intratumoral heterogeneity and interpatient tumor heterogeneity have been recognized as hurdles for efficacious cancer treatments and may result in short duration of response and resistance to classical chemotherapies. It has been shown that combinations of chemotherapy drugs with an independent mode-of-action (MoA) controls tumor growth and enhances survival in both, hematological and solid tumors.\nIn the past years, antibody-drug conjugates (ADCs) have successfully been included in cancer treatment paradigms. Recently, there has been a growing interest in dual-payload ADCs (dpADCs), i.e. ADCs consisting of two payloads conjugated to a tumor targeting antibody, for developing more efficacious ADCs. Similar to combining chemotherapy drugs, combining two payloads with independent MoA in one ADC might be an attractive strategy to address interpatient and intratumoral heterogeneity and increase response rate, duration of response, overall survival and overcome resistance. These payloads may act on (1) different cellular pathways (complementary MoA), (2) the same cellular pathway, or (3) the payloads may have a different pharmacokinetic profile, and by this dpADCs may enhance anti-tumor activity.\nPreviously, we have shown that the native glycan of monoclonal antibodies is a privileged site for attachment of cytotoxic payloads1 (GlycoConnect© technology), while the therapeutic index is further elevated by a highly polar spacer technology (HydraSpace©)2.\nHere we show that GlycoConnect© technology can readily be extended to generation of dpADCs. We have developed a modular method enabling generation of dpADCs with tailored payload ratios. In vitro and in vivo studies will be presented showcasing these GlycoConnect© dpADCs combining payloads with different MoAs.\n1Wijdeven et al., Enzymatic glycan remodeling-metal free click (GlycoConnect™) provides homogenous antibody-drug conjugates with improved stability and therapeutic index without sequence engineering. mAbs 2022, 14, doi: 10.1080/19420862.2022.2078466. \n2Verkade et al. A Polar Sulfamide Spacer Significantly Enhances the Manufacturability, Stability, and Therapeutic Index of Antibody-Drug Conjugates. Antibodies 2018, 7, 12, doi:10.3390/antib7010012.", "source_company": "Synaffix – A Lonza Company", "source_org_type": "公司", "row_number": 1194, "target_meta": "not available", "MOA_meta": "抗体偶联药物"}, {"drug_name": "ISM6210", "company": "Insilico Medicine", "org_type": "公司", "target": "CDK4", "modality": "inhibitor", "importance_level": "高", "total_score": 81, "institution_score": 85, "track_score": 80, "milestone_score": 75, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "ISM6210为高选择性CDK4抑制剂，针对CDK6毒性问题提供潜在更好安全性窗口，在HR+/HER2-乳腺癌领域有强效和良好药物性质。Insilico Medicine作为AI驱动头部biotech机构（全球AI药研领先，已上市并多PCC），赛道为热门CDK4选择性抑制（优于传统双抑），preclinical数据扎实包括体外/体内强效和安全性优势，故综合评分高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8819", "id": "-FXM_5wBX1NQZOEH-LK6", "source_drug_name": "ISM6210", "title": "ISM6210, a potent and selective CDK4 inhibitor for the treatment of HR+/HER2- breast cancer", "abstract_text": "CDK4/6 kinases drive the G1-S cell cycle transition, and overactive cyclin-CDK4/6 complexes are common across cancer types. While clinically approved CDK4/6 inhibitors have benefited patients with HR+/HER2- breast cancer, their efficacy is constrained by dose-limiting hematological toxicities, particularly CDK6-driven myelosuppression. Hematopoietic stem cell activation relies primarily on CDK6, but breast cancer cells are more dependent on CDK4, suggesting a potential therapeutic window for a CDK4-selective inhibitor. Here, we report the development and preclinical characterization of ISM6210, an orally bioavailable CDK4 inhibitor with high selectivity over CDK6.\nISM6210 demonstrated potent inhibition of the CDK4/Cyclin D1 complex in enzymatic assays with nanomolar IC50 values and good selectivity over CDK6 and other CDKs. Kinome profiling revealed minimal off-target activity, confirming its high selectivity. In cellular assays, ISM6210 selectively targeted CDK4-dependent breast cancer cells over CDK6-dependent cells. Notably, in human hematopoietic stem cell assays, ISM6210 exhibited an IC50 value about 30-fold higher than the dual CDK4/6 inhibitor Palbociclib against human hematopoietic stem cells, suggesting reduced myelosuppressive potential. Mechanistically, ISM6210 effectively blocked Rb phosphorylation and the G1/S cell cycle transition, resulting in growth arrest in HR+ breast cancer cell lines. In vivo, ISM6210 achieved robust anti-tumor activity at 30 mg/kg BID across multiple HR+ breast cancer xenograft models with notable tumor enrichment.\nIn addition to its robust biological potency and high selectivity, ISM6210 exhibited favorable drug-like properties, including desirable in vitro ADMET profiles, excellent in vivo exposure and clearance, and good oral bioavailability across multiple preclinical species. Collectively, these findings establish ISM6210 as a potent and selective CDK4 inhibitor that delivers strong efficacy and a promising hematologic safety margin for HR+/HER2- breast cancer treatment.", "source_company": "Insilico Medicine", "source_org_type": "公司", "row_number": 1280, "target_meta": "CDK4", "MOA_meta": "抑制剂"}, {"drug_name": "Amphista's SMARCA2 degraders", "company": "Amphista Therapeutics", "org_type": "公司", "target": "SMARCA2", "modality": "degrader", "importance_level": "高", "total_score": 80.5, "institution_score": 75, "track_score": 90, "milestone_score": 75, "field_heat_score": 85, "bonus_score": 8, "brief_reason": "靶向SMARCA2的Targeted Glue™ degrader，利用新型DCAF16介导机制，实现对SMARCA4缺陷肿瘤的高选择性降解。Amphista作为国外头部TPD biotech，赛道为热门degrader+新型glue机制，preclinical数据强劲包括快速深降解、体内模型验证和高分辨结构支持，综合潜力突出。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8712", "id": "cVXM_5wBX1NQZOEH-LO6", "source_drug_name": "Amphista's SMARCA2 degraders", "title": "Rational development of novel DCAF16-mediated SMARCA2 selective Targeted Glues™ for the treatment of SMARCA4 deficient tumors", "abstract_text": "SMARCA2 and SMARCA4 are mutually exclusive catalytic subunits of the SWI/SNF chromatin remodelling complex. In non-small cell lung cancer (NSCLC), SMARCA4 mutations are observed in >5% patients and are associated with poor prognosis and advanced disease. Selective degradation of SMARCA2 exploits paralogue dependency in SMARCA4-deficient tumors to impact disease burden with minimal toxicity in normal tissues​.\nHere, we report the rational design and optimisation of a novel class of SMARCA2 degraders that exploit a Targeted Glue™ mechanism to induce DCAF16-dependent proteasomal degradation. Amphista’s degraders potently drive >95% SMARCA2 degradation within 4 hours, resulting in deep suppression of biomarkers KRT80 and PLAU in vitro. Further, we observe exceptional degradation specificity for SMARCA2, as revealed by global proteomics and, critical for a best-in-class molecule, achieve near complete selectivity over SMARCA4 in a SMARCA4 WT model.\nComprehensive mode of action studies, including E3-ligase knock-out and cysteine mutant rescue experiments demonstrate that our SMARCA2 Targeted Glues™ induce degradation via selective recruitment of DCAF16 and covalent interaction with a single DCAF16 cysteine residue. Structural studies, including generation of multiple high resolution (sub-3Å) cryo EM ternary complex structures have enabled informed structure-activity relationship optimisations of degradation potency, kinetics and selectivity. Consequently, optimised compounds can deliver fast, deep degradation of SMARCA2 as demonstrated in-vivo in a disease-relevant SMARCA4 mutant model.\nWe have achieved compound profiles that uniquely position Amphista to deliver class-leading SMARCA2 degraders for the treatment of SMARCA4-mutant NSCLC.", "source_company": "Amphista Therapeutics", "source_org_type": "公司", "row_number": 54, "target_meta": "SMARCA2", "MOA_meta": "降解剂"}, {"drug_name": "SCR-A014", "company": "Simcere Pharmaceutical Group", "org_type": "公司", "target": "B7H3 x DLL3", "modality": "bispecific ADC", "importance_level": "高", "total_score": 80.5, "institution_score": 75, "track_score": 90, "milestone_score": 75, "field_heat_score": 85, "bonus_score": 6, "brief_reason": "SCR-A014为B7H3×DLL3双靶点ADC，结合双特异性与ADC机制，针对SCLC双阳性肿瘤显示优于单靶ADC的抗瘤活性。Simcere为国内头部药企，bispecific ADC+热门靶点+创新双靶策略获较高综合评分。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5389", "id": "gFXM_5wBX1NQZOEH-LO6", "source_drug_name": "SCR-A014", "title": "SCR-A014, a novel bispecific ADC targeting B7H3 and DLL3 for SCLC therapy, exhibits potent anti-tumor efficacy", "abstract_text": "Background: Small cell lung cancer (SCLC) is a most aggressive lung neuroendocrine tumor, accounting for approximately 15% of all lung cancers. Delta-like ligand 3 (DLL3) is an inhibitory Notch ligand that is highly expressed in SCLC and other neuroendocrine tumors but minimally expressed in normal tissues. B7H3, also known as CD276, is a type I transmembrane protein belonging to the B7 family that includes immune checkpoint molecules such as PD-L1, B7-1, and B7-2. DLL3 and B7H3 are highly overexpressed in small cell lung cancer (SCLC) tumor tissues, with limited presence in normal tissues, making them attractive therapeutic targets. Both B7H3 and DLL3 target shows a high positivity rate (>80%) in SCLC patient samples. However, the expression levels of DLL3 and B7H3 are not high, most samples are at a 1+ level. Moreover, B7H3 exhibits relatively slow internalization, whereas DLL3 demonstrates rapid internalization. Based on these complementary characteristics, we propose a dual-antibody drug conjugate strategy targeting both B7H3 and DLL3. This innovative approach aims to enhance antitumor efficacy.\nMethods & Results: We developed a novel B7H3 x DLL3 targeted bispecific antibody-drug conjugate (ADC) called SCR-A014, which is comprised of B7H3/DLL3 bispecific antibody conjugated with topoisomerase 1 inhibitor (CPT116). SCR-A014 specifically bind B7H3 and DLL3 with high affinity, and showed enhanced internalization and binding capacity compared to parental monoclonal antibody ADC separately in the B7H3/DLL3 co-expressing cell line. SCR-A014 induced tumor cell lysis in various tumor cell lines, and showed remarkable anti-tumor efficacy in several CDX models in a dose dependent manner. SCR-A014 exhibits significantly stronger anti-tumor activity than their parental monoclonal-ADC or clinical ADC in B7H3+DLL3+ double positive tumor cells. SCR-A014 also have very good stability and favorable developability.\nConclusion: These findings suggest that SCR-A014 is a potential first-in-class bispecific ADC and may offer a novel therapeutic strategy for SCLC cancers positive for B7H3 and DLL3.", "source_company": "Simcere Pharmaceutical Group", "source_org_type": "公司", "row_number": 111, "target_meta": "CD276,DLL3", "MOA_meta": "抗体偶联药物"}, {"drug_name": "PSTA-6208", "company": "Prospect Therapeutics", "org_type": "公司", "target": "KRAS G12V", "modality": "inhibitor", "importance_level": "高", "total_score": 80.5, "institution_score": 60, "track_score": 95, "milestone_score": 85, "field_heat_score": 90, "bonus_score": 5, "brief_reason": "PSTA-6208为口服高选择性KRAS G12V抑制剂，亚纳摩尔级细胞活性、在多种异种移植模型中实现肿瘤消退且优于RMC-5127，KRAS G12V为热门靶点且口服小分子抑制剂赛道热度高。机构为新兴biotech，preclinical数据强劲但尚未临床，综合潜力高获加分。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8815", "id": "11XM_5wBX1NQZOEH-LK6", "source_drug_name": "PSTA-6208", "title": "First disclosure of a highly potent and selective oral KRAS G12V inhibitor PSTA-6208", "abstract_text": "Introduction:\nThe KRAS G12V mutation is a major oncogenic driver in numerous cancers, promoting tumorigenesis and metastasis via constitutive activation of the MAPK pathway. Although the advent of KRAS-targeted therapy has yielded approved G12C inhibitors and clinical candidates for G12D and pan-KRAS inhibition, a significant unmet need remains for KRAS G12V-driven cancers. Here, we present PSTA-6208, a novel, orally bioavailable KRAS G12V inhibitor with sub-nanomolar cellular potency, marked efficacy in preclinical models, and high selectivity over wild-type KRAS, positioning it as a promising therapeutic candidate for KRAS G12V-positive tumors.\nMethods and Results:\nPSTA-6208 demonstrated potent and selective anti-proliferative activity in a panel of KRAS G12V-mutant cell lines, with IC₅₀ values around 0.1 nM in most cells. In head-to-head comparisons, PSTA-6208 was 17-fold more potent than RMC-5127. This activity was mechanistically linked to MAPK pathway suppression, as evidenced by inhibition of phospho-ERK in KRAS G12V-mutant CAPAN-1 cells (IC₅₀ = 1 nM). PSTA-6208 showed >500 folds selectivity over wild-type KRAS cells.\nPSTA-6208 exhibited favorable oral pharmacokinetics across multiple species, with low systemic clearance, a prolonged half-life (~10 hours), and high plasma exposure. These properties supported once-daily dosing, which achieved tumor regression in mice at doses as low as 3 mg/kg.\nPSTA-6208 induced profound, dose-dependent tumor growth inhibition and regression in multiple KRAS G12V xenograft models. In the NCI-H727 model, daily oral administration of PSTA-6208 at 1, 3, and 10 mg/kg for 21 days resulted in tumor growth inhibition (TGI) of 82%, 108%, and 112%, respectively. Notably, treatment with PSTA-6208 at 10 mg/kg led to near-complete tumor regression (complete response) by Day 21. All treatment groups were well-tolerated, with no significant adverse effects reported.\nConclusions:\nPSTA-6208 is a potent, highly selective, and orally bioavailable KRAS G12V inhibitor. Its compelling preclinical profile—including sub-nanomolar cellular potency, exceptional selectivity, favorable pharmacokinetics, and robust in vivo efficacy culminating in tumor regression at low doses—strongly supports its further development as a clinical candidate for KRAS G12V-driven cancers.", "source_company": "Prospect Therapeutics", "source_org_type": "公司", "row_number": 113, "target_meta": "KRAS G12V", "MOA_meta": "抑制剂"}, {"drug_name": "ZMS-2195", "company": "Simcere Zaiming Pharmaceutical Co, Ltd.", "org_type": "公司", "target": "Multi-RAS", "modality": "inhibitor", "importance_level": "高", "total_score": 80.5, "institution_score": 75, "track_score": 95, "milestone_score": 70, "field_heat_score": 90, "bonus_score": 3, "brief_reason": "ZMS-2195为新型高活性Multi-RAS抑制剂，可广谱阻断多种RAS变体（包括KRAS/NRAS/HRAS突变及野生型）激活MAPK通路，在多种RAS驱动肿瘤模型中显示强效抗肿瘤活性。机构为国内头部药企先声旗下肿瘤专注子公司，赛道为高热度pan-RAS抑制领域，前临床数据扎实包括体外低纳摩尔活性及体内肿瘤消退，故综合评分高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6423", "id": "clXM_5wBX1NQZOEH-LG5", "source_drug_name": "ZMS-2195", "title": "A novel highly potent multiple-RAS inhibitor ZMS-2195 efficiently blocks MAPK pathway activation and induces robust anti-tumor growth effects in preclinical models", "abstract_text": "Variants in the RAS family (HRAS, NRAS and KRAS) represent among the most prevalent oncogenic mutations identified in cancer. Approximately 19% of cancer patients harbor RAS mutations, which are typically associated with poor clinical outcomes. Multi-RAS inhibitor may overcome resistance by hitting a broader range of targets than single-mutant inhibitors. As such, multi-RAS inhibitors are anticipated to offer therapeutic potential across a wide range of RAS-driven malignancies. Here we report ZMS-2195, a novel and highly potent Multi-RAS inhibitor. Biochemical assays assessing disruption of the RAS-RAF complex demonstrated that ZMS-2195 effectively inhibited the interaction between multiple RAS variants—including KRAS, NRAS, and HRAS mutants and wild-type forms—and the RAF-RBD domain, with digital nanomolar IC50 values. The cellular MAPK pathway inhibition was confirmed through robust suppression of phosphorylated ERK in representative cancer cell lines harboring diverse RAS mutant alleles. Consistent with the biochemical activity observed against multiple RAS variants and cellular pERK inhibition potency in RAS mutant cell lines, ZMS-2195 caused potent growth inhibition of KRAS mutant cancer cell lines, exemplified by Miapaca-2 (KRASG12C/G12C, PDAC), AsPC-1(KRASG12D/G12D, PDAC) and SW403 (KRASG12V/WT, CRC) with IC50 values of 0.8, 1.3 and 0.3 nmol/L, respectively. Wild-type RAS (RASWT) cancer cells with GTP-activated RAS from upstream mutations were equally sensitive to ZMS-2195, exemplified by H1975(EGFRmut, NSCLC) with an IC50 of 6.7 nmol/L. Conversely, RASWT cancer cells harboring downstream BRAF mutations or RAS-independent normal cells were essentially insensitive to ZMS-2195. Favorable oral bioavailability and pharmacokinetic profiles were exhibited in pre-clinical species. Oral administration of ZMS-2195 resulted in dose-dependent and sustained suppression of RAS pathway signaling, as evidenced by reduced human DUSP6 mRNA expression levels in tumor lysates. Daily dosing of ZMS-2195 produced dose-dependent antitumor activity in xenograft models derived from RAS-driven human tumor xenograft model in vivo. At a dose of 0.8 mg/kg, ZMS-2195 induced tumor regression in PK59 (KRASG12D/WT, PDAC) xenograft model. In summary, ZMS-2159 is a potent Multi-RAS inhibitor with robust activity against RAS-driven tumor cells, supporting its further development as a target therapy for cancers driven by diverse RAS aberrations.", "source_company": "Simcere Zaiming Pharmaceutical Co, Ltd.", "source_org_type": "公司", "row_number": 180, "target_meta": "Ras", "MOA_meta": "抑制剂"}, {"drug_name": "XB404", "company": "Exelixis, Inc.", "org_type": "公司", "target": "ROR1/2", "modality": "ADC", "importance_level": "高", "total_score": 80.5, "institution_score": 85, "track_score": 80, "milestone_score": 75, "field_heat_score": 85, "bonus_score": 3, "brief_reason": "XB404为masked anti-ROR1/2 ADC，利用Adagene SAFEbody平台和SMARTag技术，实现肿瘤特异性递送topoisomerase 1抑制剂payload，减少脱靶毒性。Exelixis作为美国成熟肿瘤biotech公司（市值超100亿刀，已有商业化产品）+热门ADC赛道+新兴ROR1/2靶点+强效PDX模型肿瘤消退和完全缓解数据，支持IND-enabling阶段推进，综合潜力较高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4317", "id": "olXM_5wBX1NQZOEH-LG6", "source_drug_name": "XB404", "title": "Preclinical characterization of XB404, a masked anti-ROR1/2 antibody-drug conjugate", "abstract_text": "Background: Receptor tyrosine kinase-like orphan receptors (ROR) 1 and 2 are single-pass transmembrane proteins that are part of the ROR family that mediates Wnt signaling. ROR1 and ROR2 are aberrantly expressed in various cancers, including lung, breast, ovarian, and endometrial cancers, and their expression can be associated with poor disease outcomes. XB404, a masked anti-ROR1/2 antibody-drug conjugate (ADC) developed using the Adagene masking platform and the SMARTag® ADC platform, is designed to deliver a cytotoxic payload to ROR1/2-expressing tumors while minimizing on-target, off-tumor side effects. XB404 is composed of a tandem-cleavage topoisomerase 1 inhibitor-based linker-payload conjugated to a masked monoclonal antibody that binds to both ROR1 and ROR2 with high affinity. Here, we describe the preclinical characterization of XB404, including its in vitro cytotoxicity and internalization and in vivo efficacy in cell line-derived xenograft (CDX) and patient-derived xenograft (PDX) models.\nMethods: In vitro cytotoxicity of XB404 was evaluated in ROR1- and ROR2-overexpressing cell lines using the CellTiter-Glo® luminescent cell viability assay. In vitro internalization for the unmasked XB404 antibody was assessed in ROR antigen-expressing MDA-MB-231 tumor cells using flow cytometry. A rat pharmacokinetics (PK) study at 5 mg/kg was used to assess and compare PK properties for a non-masked ROR1/2 ADC and XB404. In vivo tumor growth inhibition was evaluated in Jeko-1 and MDA-MB-231 CDX models using XB404 at 7.5 mg/kg in a QWx2 dose schedule. Tumor growth inhibition was assessed in non-small cell lung cancer (NSCLC) and triple-negative breast cancer (TNBC) PDX models using 1, 3, 6, and 10 mg/kg dose levels.\nResults: Unmasked XB404 displayed potent in vitro cytotoxic activity, and unmasked XB404 antibody demonstrated internalization properties. XB404 demonstrated improved clearance and half-life compared with the non-masked ROR1/2 ADC in rats. In addition, overlapping total antibody and total ADC curves for XB404 indicated good in vivo stability. In vivo antitumor activity was observed in the Jeko-1 and MDA-MB-231 xenograft models. XB404 demonstrated dose-related tumor growth inhibition and improved survival in both NSCLC and TNBC PDX models. Tumor regression was observed in both PDX models and complete responses were observed in the TNBC PDX model.\nConclusions: XB404 demonstrated in vitro cytotoxicity and internalization, in vivo stability, and in vivo efficacy across multiple CDX and PDX models. Taken together, these preclinical results support further development of XB404. Investigational New Drug-enabling studies are ongoing.", "source_company": "Exelixis, Inc.", "source_org_type": "公司", "row_number": 190, "target_meta": "ROR1,ROR2", "MOA_meta": "抗体偶联药物"}, {"drug_name": "HA-00495", "company": "Hexagon Bio", "org_type": "公司", "target": "未披露", "modality": "ADC", "importance_level": "高", "total_score": 80.5, "institution_score": 75, "track_score": 90, "milestone_score": 75, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "HA-00495为新型蛋白翻译抑制剂payload的ADC，靶点未披露但使用TROP2/HER2抗体，Hexagon Bio作为专注新型ADC payload的国外biotech，赛道为热门ADC新机制+广谱抗瘤+耐药模型有效且NHP安全良好。机构实力较强、赛道热度高、preclinical数据扎实并进入开发阶段。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5348", "id": "8FXM_5wBX1NQZOEH-LK6", "source_drug_name": "HA-00495", "title": "HA-00495: A development candidate ADC featuring a novel protein translation inhibitor payload with broad efficacy and a favorable non human primate safety profile", "abstract_text": "Antibody drug conjugates (ADCs) have demonstrated clinical benefit across multiple cancers, yet resistance to existing payload classes, particularly topoisomerase and microtubule inhibitors, remains a major barrier to durable efficacy. To address this limitation, Hexagon Bio is leveraging its natural product discovery platform to identify new ADC payloads with mechanisms of action (MOAs) that are non-overlapping with currently approved payload classes. Enabled by our proprietary natural product library, we identified a protein translation inhibitor as a highly potent ADC payload. We conjugated the payload to a diverse panel of antibodies recognizing tumor-associated antigens and observed consistent ADC-mediated cytotoxicity across cell lines, supporting broad applicability across tumor types. In vivo, ADCs generated using anti-TROP2 (sacituzumab) and anti-HER2 (trastuzumab) antibodies demonstrated deep and durable antitumor activity in bladder, gastric, breast and lung cancer models, including models with known resistance to topoisomerase inhibitor-based ADCs. Here, we provide updated efficacy data across multiple tumor models and, for the first time, report the non-human primate (NHP) safety profile of an ADC incorporating this payload. Our new data include a comprehensive assessment of the HER2 ADC HA-00495 in NHPs, evaluating multiple dose levels as well as repeat-dose regimens. These studies reveal an acceptable safety and tolerability profile. We will present the clinical observations, clinical pathology, histopathology and key findings from these studies.In summary, we have identified a novel protein translation inhibitor payload class for ADCs that demonstrates strong efficacy, activity in resistance settings and a favorable NHP safety profile. These results support the potential of HA-00495 to address critical gaps in current ADC therapies and development activities for this candidate are now underway.", "source_company": "Hexagon Bio", "source_org_type": "公司", "row_number": 225, "target_meta": "not available", "MOA_meta": "抗体偶联药物"}, {"drug_name": "LG-LILRB1 antibody", "company": "LG Chem", "org_type": "公司", "target": "LILRB1", "modality": "antibody", "importance_level": "高", "total_score": 80.5, "institution_score": 75, "track_score": 85, "milestone_score": 85, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "靶向LILRB1阻断LILRB1/HLA-G轴，恢复T/NK/巨噬细胞抗肿瘤免疫，为first-in-class抑制剂。LG Chem作为韩国头部大型药企，preclinical数据强劲（转基因鼠肿瘤抑制88.8%、猴子长半衰期、无毒性）、已进入Phase 1临床，赛道为新兴免疫检查点热点，综合潜力高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1364", "id": "s1XM_5wBX1NQZOEH-LO6", "source_drug_name": "LG-LILRB1 antibody", "title": "LILRB1 antibody targeting the LILRB1/HLA-G axis: Preclinical efficacy, pharmacokinetics, and safety supporting first-in-human trials", "abstract_text": "Background:LILRB1 is an inhibitory receptor expressed on T cells, B cells, NK cells, and monocytes. It binds to HLA class I molecules, with the highest affinity for HLA-G. This interaction delivers inhibitory signals that allow tumor cells to evade immune surveillance, impairing NK cell, T cell, and macrophage function. Disrupting the LILRB1/HLA-G axis is a promising strategy for restoring anti-tumor immunity. Additionally, LILRB1 may regulate T cell function independently of PD-1, suggesting potential to overcome resistance to PD-1 inhibitors.\nMethods:Binding affinity and specificity of LG-LILRB1 antibody were assessed via surface plasmon resonance and flow cytometry. Competitive binding assays confirmed blockade of LILRB1/HLA-G interaction. Restoration of immune cell function was evaluated using flow cytometry and western blotting. Anti-tumor efficacy was tested in human LILRB1 transgenic mice. Pharmacokinetics and toxicokinetics were studied in cynomolgus monkeys, and safety was assessed through GLP-compliant toxicology and immunotoxicity studies.\nResults:LG-LILRB1 antibody showed high-affinity, selective binding to LILRB1 and dose-dependent blockade of HLA-G. Functional assays revealed enhanced T cell proliferation, NK cell cytotoxicity, and macrophage phagocytosis. In vivo, LG-LILRB1 antibody significantly inhibited tumor growth (up to 88.8%) in transgenic mice bearing HLA-G-expressing tumors. Pharmacodynamic analysis showed increased infiltration and activation of CD8⁺ T cells and NK cells. Combination with PD-L1 blockade yielded synergistic anti-tumor effects. In monkeys, LG-LILRB1 antibody exhibited dose-proportional exposure and a long half-life (>12 days). No treatment-related adverse findings were observed in 4-week GLP toxicity studies.\nConclusions:LG-LILRB1 antibody, a first-in-class LILRB1 blocker, restored anti-tumor immunity by disrupting the LILRB1/HLA-G axis. It enhanced immune cell function and showed strong efficacy in preclinical models. Favorable pharmacokinetics and safety support its clinical development. Combination with PD-L1 blockade further improved outcomes. These findings support LG-LILRB1 antibody as a promising candidate for cancer immunotherapy, with a Phase 1a trial currently ongoing (NCT06332755).", "source_company": "LG Chem", "source_org_type": "公司", "row_number": 245, "target_meta": "LILRB1", "MOA_meta": "抗体"}, {"drug_name": "MSLNxEpCAM-targeting Switch-DARPin", "company": "Molecular Partners AG", "org_type": "公司", "target": "MSLN & EpCAM (logic-gated AND-gate)", "modality": "TCE", "importance_level": "高", "total_score": 80.5, "institution_score": 75, "track_score": 90, "milestone_score": 75, "field_heat_score": 85, "bonus_score": 6, "brief_reason": "采用logic-gated AND-gate机制的双靶点TCE（MSLN×EpCAM），结合CD2共刺激提升实体瘤安全性与持久效能，靶点组合在卵巢癌中高共表达且正常组织低共表达。Molecular Partners作为专注DARPin平台的国外头部biotech，赛道为热门next-gen TCE+逻辑门设计，preclinical数据强劲显示显著安全性提升与肿瘤回归，整体潜力较高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4502", "id": "H1XM_5wBX1NQZOEH-LS6", "source_drug_name": "MSLNxEpCAM-targeting Switch-DARPin", "title": "Logic-gated switch-DARPin T cell engager with CD2 co-stimulation for improved safety and efficacy in MSLN and EpCAM co-expressing ovarian cancer", "abstract_text": "Introduction\nThe development of T cell engagers (TCEs) for solid tumors is challenged by the scarcity of specific tumor-associated antigens (TAAs), which limits selectivity and increases the risk of on-target/off-tumor toxicity due to antigen expression in normal tissues. In ovarian cancer (OC), immunotherapy has shown limited success, largely due to the lack of “clean” TAAs, dysfunctional T cells, and an immunosuppressive tumor microenvironment. To overcome these challenges, we engineered a multi-specific, logic-gated CD3 TCE targeting the TAAs mesothelin (MSLN) and EpCAM, with CD2-mediated co-stimulation. This conditional Switch-DARPin design employs an AND-gate mechanism, enabling CD3 engagement only upon simultaneous recognition of both TAAs. This strategy aims to deliver potent, sustained antitumor activity while minimizing systemic toxicity and off-tumor effects on single TAA-expressing healthy cells.\nMethods\nThe MSLNxEpCAM-targeting Switch-DARPin was developed using our DARPin platform. It features a masked CD3 binder that is unmasked upon dual binding to MSLN and EpCAM on tumor cells, a CD2 binder for co-stimulation, and includes a silent Fc domain for extended half-life. Preclinical safety and antitumor efficacy were evaluated in vitro and ex vivo using tumor and reporter cell lines, primary T and mesothelial cells from healthy donors, whole blood cytokine release assays, and in vivo using an OVCAR-3 xenograft model in PBMC-humanized NXG mice.\nResults\nUsing our computational workflow DARPin Compass, we identified MSLN and EpCAM as a promising TAA pair in OC, with low co-expression in healthy tissues. In vitro, the Switch-DARPin induced selective T cell cytotoxicity against tumor cells co-expressing MSLN and EpCAM, with markedly reduced activity on cells expressing only one antigen. Notably, substantially lower activity against primary human mesothelial cells was observed, compared to other clinically tested MSLN-targeting TCEs. CD2 co-engagement promoted sustained activation and proliferation of T cells, preventing exhaustion. In vivo, the Switch-DARPin exhibited suitable pharmacokinetics and achieved significant tumor regression in MSLN+EpCAM+ xenografts without systemic cytokine release. The absence of cytokine induction in human whole blood assays confirmed the favorable safety profile despite CD2 co-stimulation.\nConclusions\nCo-targeting of MSLN and EpCAM may lower the risk of on-target/off-tumor toxicity compared to single-targeting approaches. Preclinically, our logic-gated CD3xCD2 Switch-DARPin demonstrates selective antitumor activity against MSLNxEpCAM dual-positive tumors such as OC. CD2 co-stimulation further enhances T cell function without systemic activation. Together, our approach has the potential to overcome key limitations that TCE therapy faces in solid tumor indications.", "source_company": "Molecular Partners AG", "source_org_type": "公司", "row_number": 851, "target_meta": "MSLN,EpCAM", "MOA_meta": "其他"}, {"drug_name": "Synecta T1", "company": "BlueWhale Bio", "org_type": "公司", "target": "未披露", "modality": "other", "importance_level": "高", "total_score": 80.5, "institution_score": 75, "track_score": 85, "milestone_score": 80, "field_heat_score": 90, "bonus_score": 5, "brief_reason": "Synecta T1为细胞来源纳米颗粒（CDNP）平台产品，通过模拟免疫突触实现T细胞快速激活与扩增，属于细胞治疗制造创新工具。BlueWhale Bio由CAR-T先驱Carl June等创立，已进入临床应用并获FDA AMT认定，赛道热度高且具制造优化里程碑价值。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5343", "id": "RVXM_5wBX1NQZOEH-LS6", "source_drug_name": "Synecta T1", "title": "Synecta™ T1 cell-derived nanoparticles enable accelerated, potent T cell expansion for scalable adoptive immunotherapy manufacturing", "abstract_text": "Background: While Adoptive immunotherapies are expanding clinically, their translation is limited by the lack of scalable, standardized manufacturing. Critical attributes, including T-cell activation and expansion, directly impact yield and product quality. Synecta is a cell-derived nanoparticle (CDNP) platform designed to drive rapid T-cell expansion while streamlining manufacturing. Synecta T1 incorporates membrane-bound stimulatory signals (OKT3-scFv, CD86, 4-1BBL) and cytokines (IL-7, IL-15Rα/IL-15), enabling potent activation and accelerated expansion\nMethods: T cells from healthy donor (HD) and patient (PT) samples were isolated, activated, transduced, and expanded using Synecta T1 or a comparator activation system. T-cell functionality was assessed using cytotoxicity assays and repeated antigen-exposure models. Mechanistic studies included CTV proliferation, evaluation of proliferation markers, and inhibitory assays targeting immune-synapse formation. High-resolution live-cell imaging using super-resolution confocal and lattice light-sheet microscopy was used to visualize synapse architecture. Metabolic profiling was performed using Seahorse assays.\nResults: Synecta T1-expanded HD and PT T cells exhibited rapid activation (>80% CD69/CD25 by Day 2) and accelerated expansion (2.2-fold HD, 1.4-fold PT samples by Day 3) while maintaining functional fitness under repeated antigen exposure. Rapid T cell expansion, directed by Synecta T1, correlates with early proliferation, as indicated by Cell Trace Violet dilution and the upregulation of proliferation markers.CDNPs express ICAM-1, a crucial adhesion molecule that stabilizes the interaction between Antigen-Presenting Cells (APCs) and T cells via LFA-1. Inhibition of ICAM-1/LFA-1 interaction with small molecules impaired the effective engagement between Synecta and T cells, suggesting that CDNPs' enhanced performance could stem from their ability to mimic the immune synapse. In fact, high-resolution live-cell imaging of CDNP-T cell interactions using F-actin and tubulin probes revealed the assembly and maturation of immune synapses, highlighted by the development of the peripheral supramolecular activation cluster (pSMAC) and the polarized translocation of the Microtubule-Organizing Center (MTOC) toward the CDNP interface. Furthermore, Seahorse analysis revealed that Synecta T1-expanded T cells rely less on glycolysis and more on oxidative phosphorylation, indicating metabolically efficient T cell products with a memory phenotype.\nConclusions: Synecta is a first-of-its-kind ancillary material for adoptive cell therapies, enabling simpler, cost-effective manufacturing processes. This CDNP technology facilitates faster and simpler cell therapy manufacturing, consistently delivering cells with the desired attributes and yields.", "source_company": "BlueWhale Bio", "source_org_type": "公司", "row_number": 880, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "PROTAC", "company": "Protai", "org_type": "公司", "target": "未披露", "modality": "PROTAC", "importance_level": "高", "total_score": 80.5, "institution_score": 75, "track_score": 95, "milestone_score": 65, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "PROTAC作为热门的靶向蛋白降解模态，Protai的AIMS平台整合结构蛋白质组学与AI提升PROTAC理性设计能力，虽靶点未披露但技术平台应用于多个PROTAC系统并改善结构预测置信度。机构为专注蛋白质组学+AI的创新biotech，赛道热度极高且具平台技术亮点。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11073", "id": "bJ7M_5wBZznHJdnt_W7P", "source_drug_name": "PROTAC", "title": "Structural proteomics and AI powers PROTAC rational design", "abstract_text": "Proximity-inducing drugs are an emerging class of protein interaction modulators, as many cellular processes rely on the coordinated activity of proteins to support cell growth, homeostasis, regulation and communication. This is most famously exemplified by proteolysis-targeting chimera (PROTAC). PROTACs are heterobifunctional compounds consisting of two ligands joined by a linker to bring together an E3 ligase and a protein of interest and induce ubiquitination and subsequent degradation. Dozens of PROTAC drugs are being investigated in clinical trials, most notably targeting androgen receptor (AR) and BTK. The efficacy of a PROTAC molecule is driven by ternary complex formation and stability, rather than relying solely on the binary affinity of a single molecule to a single protein. Therefore, the major challenge in rational development of PROTACs is deep understanding of the dynamics and functions of complex assembly. However, protein complexes and interactions have traditionally been hard to model and are not well represented in existing protein structure resources, both experimental and computational.In this work, we present the AIMS™ platform, which integrates structural mass spectrometry (MS) data and AI modeling tools. We apply our AIMS™ platform to multiple PROTAC systems, allowing us to improve the confidence of predicted structures compared to AI alone and support rational PROTAC design.", "source_company": "Protai", "source_org_type": "公司", "row_number": 1196, "target_meta": "not available", "MOA_meta": "PROTAC"}, {"drug_name": "Helicon peptides", "company": "Parabilis Medicines Inc", "org_type": "公司", "target": "androgen receptor (agonist-bound conformation, ARON)", "modality": "degrader", "importance_level": "高", "total_score": 80.5, "institution_score": 85, "track_score": 90, "milestone_score": 60, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "Helicon peptides为新型稳定螺旋肽degrader，选择性降解激动剂结合的活性雄激素受体（ARON），针对前列腺癌中AR突变或扩增导致的耐药，提供新机制。Parabilis为头部biotech（原FogPharma，大额融资、临床平台），热门undruggable靶点+peptide degrader赛道+preclinical但POCc强，综合热度高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11427", "id": "QFXM_5wBX1NQZOEH-LS6", "source_drug_name": "Helicon peptides", "title": "Discovery of Helicon peptides that selectively degrade the agonist-bound androgen receptor (ARON) in prostate cancer", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Parabilis Medicines Inc", "source_org_type": "公司", "row_number": 1261, "target_meta": "AR", "MOA_meta": "降解剂"}, {"drug_name": "DB-1326", "company": "Duality Biologics", "org_type": "公司", "target": "TA-MUC1", "modality": "ADC", "importance_level": "高", "total_score": 80.5, "institution_score": 85, "track_score": 85, "milestone_score": 70, "field_heat_score": 80, "bonus_score": 8, "brief_reason": "DB-1326为靶向TA-MUC1的双负载ADC，采用新型双机制拓扑异构酶I抑制剂+ecteinascidin衍生物，实现优于单负载ADC的抗肿瘤活性；Duality Biologics作为ADC领域头部国内Biotech（多款管线临床阶段、BioNTech/BeiGene合作、上市市值高），赛道热门（ADC+新兴靶点+双负载创新），preclinical显示强效和广谱，支持高潜力候选物。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4047", "id": "1p7M_5wBZznHJdnt_W3O", "source_drug_name": "DB-1326", "title": "DB-1326, a novel dual-payload TA-MUC1-directed antibody-drug conjugate, shows potent antitumor efficacy in pre-clinical tumor model", "abstract_text": "Introduction: Tumor-associated mucin-1 (TA-MUC1) is a glycoform of the MUC1 protein that is aberrantly glycosylated and is highly specific expressed by cancer cells. TA-MUC1 is highly expressed in various human epithelial cancers, making it an attractive target for cancer therapies. Several antibody-drug conjugates (ADCs) targeting TA-MUC1 are in development in clinical and preclinical stage, such as DS-3939a, CAT-09-833. However, their application remains limited by inadequate efficacy, highlighting the unmet clinical need for improving the efficacy of single payload ADCs. This study presents the preclinical evaluation of a novel dual-payload TA-MUC1-targeting ADC, DB-1326, composed of a fully human IgG1 antibody specific recognize TA-MUC1 which is conjugated to a topoisomerase I inhibitor and a novel ecteinascidin derivative. The dual mechanism of DB-1326 results in potent anti-tumor effect across different tumor types with a range of MUC1 expression levels.\nMethods: Binding activity of DB-1326 to TA-MUC1 was evaluated by ELISA. The tumor selectivity between tumor cell and normal cell was evaluated via FACS analysis. The internalization of DB-1326 to tumor cell was tested by Incucyte. CTG assay was used to evaluate the cancer cell killing of DB-1326 on multiple target positive cell lines. Both cell line-derived xenograft (CDX) models and patient-derived xenograft (PDX) models were established to evaluate the in vivo efficacy of DB-1326 monotherapy.\nResults: The naked antibody of DB-1326 showed strong binding ability to TA-MUC1 but not MUC1 peptide without glycosylation and significant higher tumor selectivity than traditional MUC1 antibody. Internalization assays demonstrated that unconjugated DB-1326 was endocytosed in tumor cells expressing TA-MUC1. DB-1326 exhibited strong cytotoxicity in vitro against several tumor cell lines. DB-1326 exhibited dose-dependent tumor growth inhibition and demonstrated superior anti-tumor activity compared to the single payload ADC in both CDX and PDX models across a range of target expression.\nConclusions: DB-1326 is a novel dual-payload ADC with a TA-MUC1 antibody. It displayed high tumor cell selectivity and superior anti-tumor effects in preclinical studies. These findings support the potential of DB-1326 as a promising advanced therapeutic candidate for tumors.", "source_company": "Duality Biologics\nDuality Biologics Ltd\nDualitybio Inc.", "source_org_type": "公司", "row_number": 1270, "target_meta": "MUC1", "MOA_meta": "抗体偶联药物"}, {"drug_name": "CO-ADC-010", "company": "Corellia AI", "org_type": "公司", "target": "CDH17", "modality": "ADC", "importance_level": "高", "total_score": 80.5, "institution_score": 75, "track_score": 90, "milestone_score": 75, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "靶向CDH17的ADC（Deruxtecan payload）及同抗体骨架的RLT，在GI道肿瘤PDX模型中显示强大疗效并克服ADC耐药，突出RLT耐药克服优势。Corellia AI作为专注肿瘤ADC的AI驱动新兴biotech，赛道热门（ADC+新兴RLT+高表达靶点CDH17），preclinical数据扎实且有明显亮点。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4379", "id": "s1XM_5wBX1NQZOEH-LG6", "source_drug_name": "CO-ADC-010", "title": "A novel CDH17-targeted radioligand therapy overcomes resistance to microtubule and topoisomerase I inhibitor ADCs and achieves potent efficacy in GI-tract tumors", "abstract_text": "CDH17 (Cadherin 17) is a single-pass transmembrane protein that is highly and widely expressed in adenocarcinomas of the colon, stomach, and pancreas, as well as in subsets of ovarian and lung cancers. Here, we describe the development of a CDH17-targeted antibody-drug and a radioligand conjugate, their in vivo efficacy across a large panel of GI-tract PDX tumors, and the pharmacokinetic and safety profiles in non-human primates. A fully human monoclonal antibody against CDH17 was generated and conjugated to Deruxtecan at a DAR of 8 (CO-ADC-010). CO-ADC-010 demonstrated rapid internalization and potent CDH17-dependent cytotoxicity, along with favorable plasma stability, pharmacokinetics, and manufacturability. In a large-scale in vivo efficacy study, CO-ADC-010 achieved >90% tumor growth inhibition (TGI) in 80% of tested PDX models. This performance significantly surpassed a comparator ADC carrying MMAE at DAR 4, which showed a similar TGI in only 33% of models, suggesting better suitability of topoisomerase-based payloads for CDH17-directed delivery. In non-human primates, a single-dose exploratory toxicology study of CO-ADC-010 at 10, 30, and 45 mg/kg revealed no target-related toxicities at any dose, with all clinical and pathological findings deemed mild and reversible.Despite strong initial responses to CO-ADC-010, many tumors relapsed over prolonged treatment due to acquired resistance to the payload, while CDH17 expression was not altered. To overcome the limitations of the de novo and acquired resistance to the ADC treatments, we also developed a CDH17-targeted radioligand therapy (RLT) using the same antibody scaffold. We demonstrate that CDH17-targeted RLT shows broad and durable responses across the PDX panel, including full activity in models refractory to Deruxtecan-based ADCs, demonstrating the superiority of RLT in these indications in overcoming drug resistance and achieving durable responses. These data collectively support CDH17-targeted RLT as a promising therapeutic approach for CDH17-positive gastrointestinal malignancies.", "source_company": "Corellia AI", "source_org_type": "公司", "row_number": 1274, "target_meta": "CDH17", "MOA_meta": "抗体偶联药物"}, {"drug_name": "BCG041", "company": "Biocytogen", "org_type": "公司", "target": "B7-H3 and MUC1", "modality": "bispecific ADC", "importance_level": "高", "total_score": 80.5, "institution_score": 75, "track_score": 90, "milestone_score": 75, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "BCG041为首创双特异性ADC同时靶向B7-H3和MUC1近膜区，B7-H3为热门ADC靶点且MUC1近膜区策略克服传统难题。Biocytogen作为国内头部biotech平台型公司，赛道热门+优异PDX疗效+良好成药性获较高分。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5393", "id": "l1XM_5wBX1NQZOEH-LG6", "source_drug_name": "BCG041", "title": "BCG041: A first-in-class bispecific ADC targeting B7-H3 and the proximal membrane region of MUC1 with superior antitumor activity", "abstract_text": "BCG041 is a first-in-class fully human IgG1κ bispecific antibody-drug conjugate (ADC) targeting both B7-H3 (CD276) and the proximal membrane region of MUC1. These two tumor-associated antigens are broadly overexpressed in a wide range of epithelial malignancies and correlate with poor prognosis individually. The frequent co-expression provides a convincing rationale for dual targeting of B7-H3 and MUC1. The effectiveness of B7-H3 ADCs, such as ifinatamab deruxtecan (DS-7300), in treating small-cell lung cancer, even in patients who have received extensive prior treatment, emphasizes the significant potential of this target. On the other hand, therapies targeting MUC1 have historically encountered several obstacles: variations in glycoforms, the production of soluble MUC1 decoys due to SEA-domain cleavage, and the poor internalization of certain epitopes. These challenges can restrict the delivery of therapeutic agents and affect the therapeutic index. Targeting the proximal region of MUC1, which can decrease the shedding and enhance internalization, offers a feasible strategy to overcome these challenges. Based on this strategy, BCG041 was developed with a hydrophilic, protease-cleavable linker and a Topoisomerase-I inhibitor payload (BCPT02, DAR≈8) to enhance binding, internalization, and antitumor potency through the avidity-driven co-engagement of its two targets. The naked antibody exhibits high affinity and full cross-reactivity with both human and cynomolgus B7-H3 and MUC1. In vitro, BCG041 demonstrated stronger binding and faster internalization than naked DS-7300 or Gatipotuzumab analogs across multiple tumor cell lines. In vivo, BCG041 achieved superior antitumor efficacy compared to ADCs of naked DS-7300 or Gatipotuzumab conjugated to either BCPT02 or DXd in several patient-derived xenograft (PDX) models of lung and breast cancer. Treatment was well-tolerated, with no observed body-weight loss or overt systemic toxicity. Pharmacokinetic evaluation revealed a favorable ADC profile, and this drug demonstrates excellent developability, with CMC cell-line development currently ongoing. Together, these data position BCG041 as a highly promising next-generation bispecific ADC for B7-H3/MUC1-positive malignancies, addressing significant unmet clinical needs in breast, lung, gastro-esophageal, head-and-neck, colorectal, prostate, and ovarian cancers.", "source_company": "Biocytogen", "source_org_type": "公司", "row_number": 1287, "target_meta": "CD276,MUC1", "MOA_meta": "抗体偶联药物"}, {"drug_name": "YTHDC1 small molecule inhibitors", "company": "Transition Bio, Inc.", "org_type": "公司", "target": "YTHDC1", "modality": "inhibitor", "importance_level": "高", "total_score": 80, "institution_score": 75, "track_score": 90, "milestone_score": 75, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "靶向新型m6A reader蛋白YTHDC1的小分子抑制剂，通过破坏核内生物分子凝聚体抑制MYC驱动癌症，具有first-in-class潜力。Transition Bio为专注biomolecular condensate的创新biotech公司，preclinical数据强劲包括口服生物利用度、在体抗瘤活性及与venetoclax协同，赛道新颖热度高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8867", "id": "VVXM_5wBX1NQZOEH-LS6", "source_drug_name": "YTHDC1 small molecule inhibitors", "title": "Discovery of first-in-class YTHDC1 small molecule inhibitors for the treatment of MYC-driven cancers", "abstract_text": "The m6A reader protein YTHDC1 is essential for cancer cell survival, through its ability to form nuclear biomolecular condensates that stabilize oncogenic transcripts such as MYC. Here, we report a new class of potent, selective, orally bioavailable small-molecule inhibitors of YTHDC1. These compounds occupy the RNA binding pocket of YTHDC1 and disrupt its interaction with m6A-modified RNA at nanomolar potency in both biochemical and cellular assays. They display high selectivity for YTHDC1 over other YTH family members, selectively dissolve m6A-dependent YTHDC1 condensates without affecting unrelated condensate systems, and exhibit clean profiles across broad kinase and safety panels. The optimized leads are drug-like, orally bioavailable and possess favorable ADME and in vivo properties. Pharmacological inhibition of YTHDC1 disrupts oncogenic YTHDC1 condensates and robustly suppresses MYC signaling resulting in growth arrest, differentiation, and apoptosis of acute myeloid leukemia (AML) and additional cancer cell types, while sparing normal hematopoietic cells. These optimized inhibitors display strong single-agent anti-tumor activity across heme and solid tumor models including AML, small cell lung cancer and neuroendocrine prostate cancer. Moreover, YTHDC1 inhibition shows pronounced synergy with standard of care agents such as venetoclax in AML. Collectively, these findings establish YTHDC1 as a tractable therapeutic target for MYC-driven malignancies.", "source_company": "Transition Bio, Inc.\nTransition Bio Ltd.", "source_org_type": "公司", "row_number": 74, "target_meta": "YTHDC1", "MOA_meta": "抑制剂"}, {"drug_name": "LUA005", "company": "Shanghai Qilu Pharmaceutical Research and Development Center LTD.", "org_type": "公司", "target": "EGFR/cMET", "modality": "ADC", "importance_level": "高", "total_score": 79.8, "institution_score": 65, "track_score": 92, "milestone_score": 82, "field_heat_score": 88, "bonus_score": 6, "brief_reason": "LUA005为EGFR/cMET双特异性ADC，采用bivalent设计+新型topo-1抑制剂payload，旨在扩大治疗窗并覆盖异质性肿瘤。Qilu为国内头部药企，ADC+热门双靶点赛道热度高，前临床数据强（优于benchmark、PDX广谱有效、NHP耐受性好），综合重要性高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5450", "id": "3FXM_5wBX1NQZOEH-LK6", "source_drug_name": "LUA005", "title": "Preclinical development of LUA005: A differentiated bivalent EGFR/cMET bispecific ADC displays strong anti-cancer efficacy and a wider therapeutic window", "abstract_text": "Background Compensatory functions between EGFR- and cMET-mediated signaling contribute to resistance to either EGFR- or cMet-targeting agents such as osimertinib. The frequent co-expression of these two targets in solid tumors supports dual targeting strategy, evidenced by the approved bispecific antibody amivantamab. Several EGFR-cMET antibody-drug conjugates (ADCs) have entered clinical trials. While most bispecific ADCs targeting EGFR and cMET use a 1+1 format, we designed and generated LUA005 with bivalent arms for each target. It exhibits low affinity but high avidity to EGFR, coupled with high-affinity to cMET. This design aims to minimize on-target off-tumor toxicity while ensuring robust efficacy across heterogeneous tumors, including those with low EGFR expression. Here, we report the preclinical characterizations of LUA005 as an EGFR/c-Met bispecific ADC with differentiated properties. Methods LUA005 was built on the QILU's proprietary novel topoisomerase-1 inhibitor platform, conjugated via a hydrophilic cleavable linker to yield a uniform DAR 8 product. The payload displayed nanomolar activity across various cancer cell lines and much faster systematic clearance than Dxd in vitro, to reduce systematic toxicity. Benchmark ADCs were included for comparison. Results In vitro, LUA005 exhibited strong cytotoxicity against tumor cell lines but minimal killing of normal keratinocytes, indicating a wider therapeutic window than benchmarks. Meanwhile, LUA005 demonstrated superior antitumor activity compared to benchmarks across a spectrum of CDX models with different EGFR and cMET expression levels, highlighting its potential to address tumor heterogeneity. LUA005 also demonstrated remarkable efficacy in a series of patient-derived xenograft (PDX) models, including those resistant to osimertinib, cetuximab, or immunotherapy. Meanwhile, LUA005 was well tolerated in Cyno monkeys, with HNSTD up to 60 mpk Q3W for three times repeated dosing in NHP toxicity study, without obvious on-target toxicity or ILD, consistent with our molecule design. LUA005 demonstrated favorable PK profile in cyno monkeys, with high stability and limited free drug release in circulation. Conclusions LUA005, an EGFR/cMET bispecific ADC with differentiated molecular design, demonstrated superior antitumor efficacy with enhanced therapeutic index. Preclinical studies warranted its further development into clinical trials, which are anticipated to start in early 2026.", "source_company": "Shanghai Qilu Pharmaceutical Research and Development Center LTD.", "source_org_type": "公司", "row_number": 121, "target_meta": "EGFR,c-Met", "MOA_meta": "抗体偶联药物"}, {"drug_name": "PBI-381", "company": "Polymed Biopharmaceuticals", "org_type": "公司", "target": "KRasG12D", "modality": "PROTAC", "importance_level": "高", "total_score": 79.8, "institution_score": 65, "track_score": 95, "milestone_score": 82, "field_heat_score": 90, "bonus_score": 6, "brief_reason": "PBI-381为针对KRasG12D的PROTAC降解剂，在热门靶点KRasG12D+热门赛道PROTAC上展现优异体外/体内活性，并在胰腺癌异种移植瘤模型中实现肿瘤显著消退，优于临床最先进同类ASP3082。Polymed为国内Biotech公司，preclinical数据扎实且IND-enabling已启动，综合潜力突出。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8699", "id": "SlXM_5wBX1NQZOEH-LO6", "source_drug_name": "PBI-381", "title": "PBI-381, a development candidate PROTAC for KRasG12D solid tumors", "abstract_text": "Kras gain-of-function mutations are prominent cancer drivers in pancreatic, colorectal, lung and other solid tumors. While several small molecule inhibitors against KRasG12C have been approved to treat non-small cell lung and colorectal cancers, either as single agent or in combination, there is still a great unmet need for other more prevalent Kras mutations such as KrasG12D. Furthermore, given the complexity of KRasG12D molecular mode of action and its downstream signaling branches, whether complete elimination of the KRasG12D protein or functional inhibition of its signaling activity has a bigger impact on cancer cells remains an open question. Therefore, Proteolysis Targeting Chimera (PROTAC)-based Kras degraders may bring differentiated clinical benefits to patients with Kras-mutant solid tumors. At present, ASP3082 (Astellas Pharma) and PT0253 (PAQ Therapeutics) are the only two KRasG12D PROTAC degraders that have entered clinical trials.Polymed Biopharmaceuticals has generated a series of potent and selective PROTAC molecules targeting the KRasG12D mutant protein. In vitro, these PROTAC molecules exhibited DC50 (degradation IC50) < 1 nM and Dmax (maximal % of degradation) > 98% against KRasG12D in cancer cell lines harboring this mutation. Moreover, as measured by cancer cell growth inhibition, the Polymed PROTAC molecules are highly selective against cells with the KRasG12D mutation while sparing cells harboring KRasG12V, KRasG12C or cells with amplified wild type KRas. More importantly, in KRasG12D pancreatic cancer xenograft model PK59, treatment with the lead molecule PBI-381 resulted in robust tumor regression without impact on body weight and any other noticeable adverse effects on the mice after 4 weeks of treatment. A good PK/PD/efficacy relationship was also observed with PBI-381. Preliminary ADME, in vitro safety and drug-drug interaction assessments further supported PBI-381 as a development candidate for advancing into the clinic.Compared to the most clinically advanced KRasG12D PROTAC ASP3082, PBI-381 has superior potency and more favorable tissue distribution for a drug designed to treat solid tumors. In head-to-head comparison studies using xenograft models, PBI-381 also exhibited significantly higher anti-tumor activity than ASP3082. IND-enabling activities on PBI-381 are underway to progress the compound further towards the clinic.", "source_company": "Polymed Biopharmaceuticals", "source_org_type": "公司", "row_number": 1237, "target_meta": "KRAS G12D", "MOA_meta": "PROTAC"}, {"drug_name": "BCG036", "company": "Biocytogen", "org_type": "公司", "target": "PD-1×VEGF-A", "modality": "bispecific antibody", "importance_level": "高", "total_score": 79.5, "institution_score": 75, "track_score": 90, "milestone_score": 70, "field_heat_score": 85, "bonus_score": 3, "brief_reason": "BCG036为PD-1×VEGF-A双特异性抗体，通过同时阻断PD-1/PD-L1和VEGF/VEGFR通路实现免疫+抗血管生成协同抗瘤。Biocytogen作为国内头部biotech，赛道为热门PD-1/VEGF双抗，preclinical数据优于benchmark且猴子毒理安全良好，综合热度高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4525", "id": "VlXM_5wBX1NQZOEH-LS6", "source_drug_name": "BCG036", "title": "A half-life extended PD-1×VEGFA bispecific antibody demonstrates potent anti-tumor activity in preclinical models", "abstract_text": "Background PD-1 blockade reactivates T-cell-mediated tumor killing but faces resistance in \"cold\" tumors with poor immune infiltration. VEGF-A inhibition (e.g., bevacizumab) normalizes tumor vasculature, enhancing immune cell delivery and synergizing with PD-1 inhibitors. Simultaneously disrupts immune evasion (via PD-1) and tumor blood supply (via VEGF-A), addressing microenvironmental barriers. Currently, several PD-1/L1×VEGF-A bispecific antibodies have been developed and demonstrated superior antitumor activity.\nMethods We developed a novel PD-1×VEGF-A bispecific antibody, BCG036, by fusing a fully human anti-VEGF-A VHH domain with an Fc-engineered IgG1 anti-PD-1 monoclonal antibody to extend its half-life. We used reporter cell lines to conduct blocking assays for PD-1 and VEGF-A. In vivo pharmacokinetic and efficacy studies were evaluated in FcRn humanized mice and xenograft mouse models bearing an established A375 tumor. Toxicology studies were conducted in cynomolgus monkeys to assess the safety and pharmacokinetic characteristics of the BCG036.\nResults BCG036 demonstrated high affinity and specificity for both human PD-1 and VEGF-A, with superior blocking activity for both PD-1/PD-L1 and VEGF/VEGFR signaling\npathway than the benchmark. In vivo, BCG036 exhibited an extended half-life in humanized FcRn mice and demonstrated potent antitumor efficacy than the benchmark. Importantly, BCG036 displayed a favorable safety and PK profile in cynomolgus monkeys after repeated dosing at 100 mg/kg.\nConclusions Our prolonged half-life version of the PD-1×VEGF-A bispecific antibody shows high affinity in vitro and has a strong ability to block the interactions of PD-1/PD-L1 and VEGFR2/VEGFA. It demonstrates strong antitumor activity in mouse models and has demonstrated good safety in cynomolgus monkeys, supporting a long-term dosing regimen.", "source_company": "Biocytogen", "source_org_type": "公司", "row_number": 106, "target_meta": "PD1,VEGF-A", "MOA_meta": "双特异性抗体"}, {"drug_name": "VTS208", "company": "VelaVigo (Hong Kong) Limited", "org_type": "公司", "target": "CD3/CLDN18.2/CDH17", "modality": "TCE", "importance_level": "高", "total_score": 79.5, "institution_score": 75, "track_score": 92, "milestone_score": 65, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "VTS208为首创三特异性TCE，同时靶向CD3、CLDN18.2和CDH17，解决GI癌肿瘤异质性和抗原丢失耐药问题，机制创新且针对热门靶点。VelaVigo为国内新兴biotech，已获超1.6亿美元融资并实现多次out-licensing，赛道为热门trispecific TCE+GI癌未满足需求，但仍处CMC优化和毒性研究阶段，IND计划2026下半年。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4545", "id": "4lXM_5wBX1NQZOEH-LC5", "source_drug_name": "VTS208", "title": "VTS208: A first-in-class CD3/CLDN18.2/CDH17 Tri-specific T cell engager (TCE) for the treatment of gastrointestinal (GI) cancer", "abstract_text": "Zolbetuximab (Astellas’ anti-CLDN18.2 mAb, approved) has validated CLDN18.2 as a promising tumor-associated antigen (TAA) for gastrointestinal (GI) cancer therapy. CLDN18.2-targeting T cell engagers (TCEs), including IBI389 (phase I) and ASP2138 (phase I), demonstrate anti-tumor activity in patients with low CLDN18.2 expression, indicating that the TCE modality is effective even with minimal TAA expression. However, short duration of response and drug resistance persist because tumor heterogeneity drives therapeutic limitations. Notably, CDH17 (Cadherin 17) has emerged as a novel biologic target, frequently overexpressed in GI cancers. CLDN18.2 and CDH17 exhibit highly complementary expression patterns (co-expressed or individually expressed) across multiple cancers with limited normal tissue expression, positioning them as ideal dual targets for trispecific TCE design that may address tumor heterogeneity and overcome antigen-loss resistance in single-target therapies.\nWe present VTS208, a first-in-class trispecific antibody featuring a proprietary CD3 arm that targets both CLDN18.2 and CDH17. It achieves potent on-target cytotoxicity with reduced concomitant T cell activation, thereby widening the therapeutic window. Its bi-paratopic CDH17-targeting design enhances binding avidity and efficacy against low-expression tumors. In human PBMC-reconstituted CDX models with variable CLDN18.2/CDH17 expression across gastric cancer (GC), pancreatic ductal adenocarcinoma (PDAC) and colorectal cancer (CRC), VTS208 demonstrated robust anti-tumor activity even at low doses. Preliminary cynomolgus monkey toxicity studies confirmed favorable tolerability under step-up dosing. Current development includes CMC process optimization and dose-range-finding (DRF) toxicity studies. With mini-pool fermentation titers of 4-6 g/L supporting targeted drug substance concentrations for subcutaneous administration, the IND application is scheduled for filing in H2 2026.\nIn summary, VTS208’s unique trispecific design and differentiated features demonstrate promising efficacy and safety, positioning it as a compelling first-in-class TCE candidate for clinical development.", "source_company": "VelaVigo (Hong Kong) Limited", "source_org_type": "公司", "row_number": 129, "target_meta": "CD3,CLDN18.2,CDH17", "MOA_meta": "其他"}, {"drug_name": "BLU-448", "company": "Blueprint Medicines", "org_type": "公司", "target": "CDK4", "modality": "degrader", "importance_level": "高", "total_score": 79.5, "institution_score": 85, "track_score": 90, "milestone_score": 60, "field_heat_score": 85, "bonus_score": 3, "brief_reason": "BLU-448为Blueprint Medicines开发的 potent and selective CDK4 degrader，针对HR+/HER2-乳腺癌，具有创新的蛋白降解机制，赛道热门且公司为头部biotech。摘要embargoed导致开发阶段细节有限，但preclinical表征显示清晰潜力。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11310", "id": "qVXM_5wBX1NQZOEH-LS6", "source_drug_name": "BLU-448", "title": "Characterization of BLU-448: A potent and selective degrader of CDK4 for the treatment of HR+/HER2- breast cancers", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Blueprint Medicines", "source_org_type": "公司", "row_number": 135, "target_meta": "CDK4", "MOA_meta": "降解剂"}, {"drug_name": "KIR-CAR T", "company": "Verismo Therapeutics", "org_type": "公司", "target": "EGFR", "modality": "CAR", "importance_level": "高", "total_score": 79.5, "institution_score": 75, "track_score": 90, "milestone_score": 70, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "该药物为靶向EGFR的KIR-CAR T细胞疗法，利用新型多链NK细胞信号克服传统CAR T在胶质母细胞瘤中的功能缺陷，实现体内清除耐药肿瘤。Verismo由Kymriah发明者创立，专注固瘤CAR T创新平台，赛道为热门细胞治疗+固瘤突破+新机制，preclinical数据强劲且具转化潜力。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11517", "id": "HZ7M_5wBZznHJdnt_W7O", "source_drug_name": "KIR-CAR T", "title": "Natural killer cell-based signaling in EGFR-targeted KIR-CAR T overcomes CD3-based CAR T functional deficits to eliminate resistant glioblastomas in vivo", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Verismo Therapeutics", "source_org_type": "公司", "row_number": 161, "target_meta": "EGFR", "MOA_meta": "其他"}, {"drug_name": "MAC-8001", "company": "DaCure Therapeutics", "org_type": "公司", "target": "KRAS", "modality": "other", "importance_level": "高", "total_score": 79.5, "institution_score": 65, "track_score": 95, "milestone_score": 75, "field_heat_score": 90, "bonus_score": 5, "brief_reason": "MAC-8001为KRAS靶向的molecular glue-antibody conjugate（MAC），通过破坏RAS-BRAF相互作用抑制KRAS突变癌信号通路。机构为2024年成立的中国新兴biotech，得分中等偏上；KRAS热门靶点+新型分子胶-抗体偶联物赛道极热，preclinical阶段展示强效体内外抗肿瘤活性及良好耐受性，故综合评分高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5493", "id": "LFXM_5wBX1NQZOEH-LG5", "source_drug_name": "MAC-8001", "title": "MAC-8001: A KRAS-targeting molecular glue-antibody conjugate with robust antitumor activity in KRAS-mutant cancers", "abstract_text": "Background\nKRAS mutations are among the most frequent oncogenic drivers, occurring in approximately 10-15% of all human cancers and in over 90% of pancreatic ductal adenocarcinomas (PDAC). Although KRAS G12C inhibitors have achieved clinical success, the majority of KRAS mutations (>85%), predominantly G12D and G12V, remain without approved targeted therapies. Recently, several G12D/V-selective inhibitors and pan-RAS molecular glues (MGs) have emerged as promising strategies to address this unmet need. Converting KRAS-targeting MGs into molecular glue-antibody conjugates (MACs) offers an attractive avenue to further optimize their therapeutic window by limiting systemic exposure, improving pharmacokinetics, and enhancing clinical translatability.\nMethods\nA series of KRAS-modulating MG payloads were developed through structure-based optimization and subsequently site-specifically conjugated to an anti-B7H3 antibody via a cleavable linker, yielding the conjugate MAC-8001. The conjugate was characterized by reversed-phase liquid chromatography (RPLC) and size-exclusion chromatography (SEC) to determine its drug-to-antibody ratio (DAR) and aggregation profile, respectively. The capacity of the payloads to interfere with RAS-BRAF RBD interactions was evaluated using a TR-FRET assay. In vitro antiproliferative activities were evaluated across cancer cell lines harboring KRAS G12C/D/V mutations, while in vivo efficacy and pharmacodynamic responses were examined in corresponding xengraft models.\nResults\nThe conjugate exhibited a DAR of approximately 8.0 with no detectable aggregation. MAC-8001 demonstrated potent and selective inhibition of KRAS-mutant cancer cells (IC₅₀ <10 nM) compared with KRAS wild-type counterparts, accompanied by pronounced, dose-dependent suppression of downstream p-ERK and p-AKT signaling. Consistent with its scaffold-derived mechanism, TR-FRET assays confirmed that the payloads disrupted RAS-BRAF interactions, thereby attenuating MAPK signaling. In xenograft mouse models, a single intravenous dose of MAC-8001 produced durable antitumor responses, achieving over 90% tumor growth inhibition. Moreover, MAC-8001 was well-tolerated, without body-weight loss or detectable systemic toxicity.\nConclusions\nMAC-8001 represents a potent KRAS-targeting MAC that selectively inhibits KRAS-driven signaling and exhibits robust antitumor efficacy both in vitro and in vivo. The modular design of this MAC platform allows straightforward adaptation to other tumor-associated antigens,\nsuch as TROP2, thereby broadening its translational potential across RAS-driven malignancies. Collectively, these findings establish a novel therapeutic paradigm that may overcome the inherent limitations of systemic KRAS modulation.", "source_company": "DaCure Therapeutics", "source_org_type": "公司", "row_number": 177, "target_meta": "KRAS", "MOA_meta": "其他"}, {"drug_name": "EGFR-γδTCE", "company": "WuXi Biologics", "org_type": "公司", "target": "EGFR", "modality": "bispecific antibody", "importance_level": "高", "total_score": 79.5, "institution_score": 75, "track_score": 90, "milestone_score": 70, "field_heat_score": 85, "bonus_score": 8, "brief_reason": "EGFR-γδTCE为新型pan-γδ T cell engager双抗，靶向EGFR，利用γδT细胞避免传统CD3 TCE的CRS和on-target/off-tumor毒性，在体外和体内模型显示优于临床基准的杀伤活性和安全性。WuXi Biologics作为全球领先生物药CRDMO平台公司，赛道为热门的γδTCE+实体瘤热门靶点EGFR，preclinical数据强劲且平台潜力大故高分。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4496", "id": "alXM_5wBX1NQZOEH-LG5", "source_drug_name": "EGFR-γδTCE", "title": "A novel pan-gamma-delta T cell engager platform for next-generation cancer therapeutics", "abstract_text": "Bispecific T cell engagers (TCEs) are potent immunotherapeutic molecules that redirect the body’s T cells to kill tumor or pathogenic cells by bridging CD3 and tumor-associated antigen (TAA). Over the past decade, TCE-based therapies have achieved great success for the treatment of liquid tumors. However, although there is a multitude of TCEs with solid tumor targets in preclinical and clinical development, only one DLL3-targeting TCE was approved by FDA. For most TCEs targeting solid tumors, the main concern is on-target/off-tumor cytotoxicity, that is target organ toxicity due to redirection of T cells to normal tissues expressing the TAA. In addition, excessive release of cytokines may also translate to potentially life-threating cytokine release syndrome (CRS). To expand the therapeutic index and bring more treatment options to patients, there are intense efforts to overcome these challenges. Gamma-Delta T (γδT) cells can leverage both innate and adaptive immunity to combat target cells. Gamma-delta T cell engager (γδTCE) is a novel antitumor therapeutic to redirect γδ T cells to eliminate tumor or other pathogenic cells without pan T cell activation, therefore resulting in improved therapeutic index compare to pan T cell engager. To test this hypothesis, WuXi Biologics has developed a novel and unique pan-γδ TCE platform for the undruggable or hard-to-drug TAAs, that CD3 TCE can’t target. Epidermal growth factor receptor (EGFR) is highly expressed in many solid tumors (e.g. non-small cell lung cancer and colorectal cancer) and low in normal tissues. EGFR has been clinically validated by multiple drug modalities, such as monoclonal antibodies and antibody-drug conjugates. However, EGFR x CD3 TCE, which may be the most powerful therapeutic modality, remains undruggable due to severe adverse effects of cytokine release and on-target/off-tumor toxicities. WuXi Biologics’ EGFR-γδTCE is able to motivate diverse γδ T cell populations with equivalent activity, inducing significant expansion of γδ T cells without causing exhaustion. Compared with the clinical Vδ1 and Vδ2 benchmarks, WuXi Biologics’ EGFR-γδTCE showed more efficient cytotoxicity against tumor cells, while sparing healthy cells and maintaining low cytokines. In in vivo antitumor studies of human colorectal cancer HCT116 xenograft models, the EGFR-γδTCE also exhibited superior antitumor efficacy than the clinical benchmarks. The studies support WuXi Biologics’ EGFR-γδTCE as a promising novel therapeutic to target multiple solid tumors with EGFR expression and also demonstrate that WuXi Biologics’ γδTCE platform has the potential to become best-in-class and can be applied to the undruggable or hard-to-drug TAAs.", "source_company": "WuXi Biologics", "source_org_type": "公司", "row_number": 179, "target_meta": "EGFR", "MOA_meta": "双特异性抗体"}, {"drug_name": "YL413", "company": "MediLink Therapeutics (Suzhou) Co., Ltd.", "org_type": "公司", "target": "HER2", "modality": "ADC", "importance_level": "高", "total_score": 79.5, "institution_score": 75, "track_score": 90, "milestone_score": 70, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "YL413为新型双负载（topoisomerase 1抑制剂+微管抑制剂）anti-HER2 ADC，旨在克服单负载ADC（如Enhertu）耐药，靶点HER2在乳腺癌等领域成熟且热门。机构为国内专注ADC的领先biotech，已有多个项目临床并与Roche/BioNTech合作，赛道双负载+HER2热度高，preclinical显示优于单负载及在耐药模型有效。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4322", "id": "dVXM_5wBX1NQZOEH-LG5", "source_drug_name": "YL413", "title": "YL413: A novel dual-payload anti-HER2 antibody-drug conjugate demonstrating potent preclinical activity", "abstract_text": "Antibody Drug Conjugates (ADC) have achieved great success as anti-cancer therapies, with 21 ADC drugs approved in the global market. Despite the initial response to ADC treatment, drug resistance and tumor relapse inevitably happen, driven by high heterogeneity in advanced tumors. Overcoming these resistance mechanisms is a critical challenge to next-generation ADC development for cancer therapy. To address these challenges, we developed YL413, a novel anti-HER2 ADC with two payloads of different MOAs: a topoisomerase 1 inhibitor and a microtubulin inhibitor. This dual-payload strategy is designed to mitigate resistance associated with single-agent therapies. YL413 was engineered with an appropriate drug-to-antibody ratio (topoisomerase I inhibitor to microtubule inhibitor) to optimize the therapeutic window. Trastuzumab, topoisomerase I inhibitors, and microtubule inhibitors were expected to demonstrate anti-tumor activity in clinical trials. In vitro, YL413 demonstrated comparable binding and internalization in the HER2+ cell line to Trastuzumab. YL413 demonstrated better cytotoxicity than Mon-payload ADCs against tumor cells in vitro. In Vivo, the dual-payload ADC exhibited superior efficacy in CDX models and the Ehertu-resistance models. In summary, we developed HER2 dual-payload ADCs to address Topo1 inhibitor-induced tumor resistance. The dual-payload HER2 ADC exhibited strong anti-tumor activity in vitro and in vivo, indicating potential to overcome Enhertu® resistance. YL413 retains Topo1 inhibitor efficacy, supplemented by a microtubule inhibitor, with possible use in earlier treatment lines.", "source_company": "MediLink Therapeutics (Suzhou) Co., Ltd.", "source_org_type": "公司", "row_number": 181, "target_meta": "HER2", "MOA_meta": "抗体偶联药物"}, {"drug_name": "BCG039", "company": "Biocytogen", "org_type": "公司", "target": "Nectin-4×TROP2", "modality": "bispecific ADC", "importance_level": "高", "total_score": 79.5, "institution_score": 75, "track_score": 90, "milestone_score": 70, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "BCG039为靶向Nectin-4和TROP2的双特异性ADC，在mUC等实体瘤模型中显示优于单靶点ADC的抗肿瘤活性，采用新型TOP1抑制剂payload并进入CMC开发。Biocytogen作为国内头部biotech平台公司，ADC+双靶点热门赛道加持，preclinical数据强劲且具潜在毒性降低优势。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5392", "id": "j1XM_5wBX1NQZOEH-LG6", "source_drug_name": "BCG039", "title": "Preclinical study of BCG039, a Nectin-4×TROP2 bispecific ADC, in urothelial carcinoma and other solid tumor models", "abstract_text": "Background: Urothelial carcinoma (UC) affects over 600,000 patients worldwide annually, with the incidence rate increasing over the past decade. Metastatic urothelial carcinoma (mUC) has a poor prognosis, with the 5-year survival rate estimated to be as low as 10-15%.Nectin-4 is highly expressed in mUC. It is a clinically validated target for mUC with enfortumab vendotin (EV) and pembrolizumab combination as the newly established SOC for first-line metastatic and locally advanced UC. TROP2 is also highly expressed in UC, and sacituzumab govetecan (SG) has shown therapeutic activity in later-line mUC. Nectin-4xTROP2 bsADC aims to target these two clinically validated targets in mUC to further improve efficacy and reduce toxicity.\nMethod: Fully human antibodies against Nectin-4 and TROP2 were generated with Biocytogen's RenLite® transgenic mice. We selected the arms of the bispecific antibody based on their internalization activities in constructing and evaluating the bispecific antibody in a 1+1 format. The bispecific antibody was conjugated to both vcMMAE at DAR of 4 and Biocytogen’s proprietary linker-payload BLD1102 at DAR of 4, respectively. BLD1102 is composed of a novel TOP1 inhibitor payload and a highly hydrophilic and enzyme-cleavable linker. The resulting ADCs were tested in CDX and PDX tumor models in mice, along with relevant benchmark ADCs for anti-tumor activity.\nResults: We selected the arms based on their internalization activities, with the nectin-4 arm and the TROP2 arm showing enhanced internalization capability in the format of 1+1 bispecific antibody vs the respective monovalent parental arms, suggesting cooperative interactions of the two arms. Consistent with this in vitro observation, the vcMMAE conjugated bispecific ADC (bsADC) exhibited markedly increased anti-tumor activity compared with the monovalent parental ADCs in mouse CDX/PDX models. BCG039, the BLD1102-conjugated bsADC, also demonstrated tumor growth inhibition superior to benchmark anti-nectin-4 and certain benchmark anti-TROP2 ADCs. The bispecific antibody has excellent developability and is now in CMC development.\nConclusion: BCG039, a bsADC targeting Nectin-4 and TROP2, showed superior anti-tumor efficacy in mice compared to single-targeting parental ADCs and relevant benchmark ADCs. The cooperative interaction of the two arms may also help reduce the toxicity observed with single-targeting ADCs against these targets in mUC.", "source_company": "Biocytogen", "source_org_type": "公司", "row_number": 186, "target_meta": "NECTIN4,TROP2", "MOA_meta": "抗体偶联药物"}, {"drug_name": "LM-364TME", "company": "LaNova Medicines", "org_type": "公司", "target": "Nectin-4", "modality": "ADC", "importance_level": "高", "total_score": 79.5, "institution_score": 75, "track_score": 90, "milestone_score": 70, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "LM-364TME为条件激活型anti-Nectin-4 ADC，利用TME高ANP实现肿瘤特异性结合，显著改善安全性并保留强效抗瘤活性；LaNova作为国内创新biotech（后被三生制药收购），专注next-gen ADC平台，Nectin-4 ADC赛道热度高且preclinical数据优秀，支持较高综合评分。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5414", "id": "MVXM_5wBX1NQZOEH-LK6", "source_drug_name": "LM-364TME", "title": "Preclinical evaluation of LM-364TME: A next-generation anti-Nectin4 ADC with promising efficacy and reduced toxicity", "abstract_text": "Background: Antibody-drug conjugates (ADCs) has shown significant efficacy across multiple tumor types. Nectin-4, an adhesion molecule with limited expression in normal tissues (restricted to skin and secretory glands), is overexpressed in bladder, triple-negative breast, and other epithelial cancers. The clinical success of enfortumab vedotin valudated Nectin-4 as a therapeutic target; however, dose-limiting skin rash and neuropathy arise from on target, off-tumor toxicity due to low Nectin-4 epxression in nomal tissues. Extracelluar adenine nucleotides (ANP:ATP/ADP/AMP) accumulate to micromolar concentrations within the tumor microenvironment (TME), while remaining at nanomolar levels in heathy tissues. LM-364TME is a novel anti-Nectin-4 ADC designed to exploit this metabolic difference. It comprises a humanized antibody endineered for ANP-dependent binding to Nectin-4, conjugated via a cleavable linker to topoisomerase I inhibitor payload, with a drug-to-antibody ration of 8.\nMethods: Binding activity, specificity, and cross-species reactivity of LM-364TME were evaluated by flow cytometry. Internalization was evaluated using a pH-sensitive fluorescent probe. Cytotoxicity was measured via CellTiter-Glo luminescent cell viability assay. In vivo anti-tumor activity of LM-364TME was evaluated in Nectin 4-positive cell line-derived xenografts (CDX) and patient-derived xenografts (PDX) models. Repeated-dose toxicity studies were performed in Sprague-Dawley rats and rhesus monkeys.\nResults: LM-364TME exhibited strong ANP-dependent binding to Nectin 4, with an EC50 of 0.02 nM to huNectin4 protein and 0.187 -1.837 nM in Nectin-4 positive tumor cells under high ANP conditions, butnegligible binding in the absence of ANP, resulting a large selectivity window. LM-364TME also exhibited cross-reactivity with Nectin-4 in rodent and non-human primate models. LM-364TME showed robust ANP-dependent internalization and cytotoxicity in in MDA-MB-468 and huNectin 4 CHOK1 cells. In vivo, LM-364TME treatment (3-6 mg/kg) significantly induced tumor growth and regression in multiple models, including MDA-MB-468 (TGI 119.1%), urothelial carcinoma PDX (TGI 107.46%) , esophageal cancer PDX (TGI 86.73%), and cervical cancer PDX (TGI 168.79%). In repeat-dose studies, LM-364TME was well tolerated in both rats and rhesus monkeys.\nConclusion: LM-364TME is an ANP-dependent, conditionally active anti-Nectin-4-ADC that demonstrates potent and selective antitumor activity with favorable safety profile in preclinical models. These data support LM-364TME as a promising next-generation Nectin-4-targeted therapy with the potential to improve the therapeutic index of this class.\nKeywords: Nectin-4, antibody-drug conjugate, LM-364TME, solid tumors\nDisclosure: The study was funded by LaNova Medicines Limited, China.", "source_company": "LaNova Medicines", "source_org_type": "公司", "row_number": 212, "target_meta": "NECTIN4", "MOA_meta": "抗体偶联药物"}, {"drug_name": "RCZY-869", "company": "Rongchang Pharmaceuticals, Ltd.", "org_type": "公司", "target": "KRASG12D (ON-state)", "modality": "inhibitor", "importance_level": "高", "total_score": 79.5, "institution_score": 75, "track_score": 95, "milestone_score": 65, "field_heat_score": 90, "bonus_score": 3, "brief_reason": "RCZY-869为口服共价三元复合物抑制剂，特异靶向GTP结合的KRASG12D（ON态），通过CypA形成稳定复合物阻断MAPK信号。荣昌制药在KRAS G12D热门赛道中展现较强体外/体内优于竞品RMC-9805的preclinical数据，综合热度高但仍处临床前阶段。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8732", "id": "w1XM_5wBX1NQZOEH-LS6", "source_drug_name": "RCZY-869", "title": "RCZY-869: A highly potent, selective, and orally bioavailable covalent KRASG12D (ON-state) inhibitor with robust antitumor activity in preclinical models of KRASG12D-driven solid tumors", "abstract_text": "KRASG12D is the most prevalent oncogenic mutation in the RAS family. Among common solid tumors, it drives approximately 40% of pancreatic ductal adenocarcinoma (PDAC), 15% of colorectal cancer (CRC), and 5% of non-small cell lung cancer (NSCLC) cases, underscoring a significant unmet clinical need for targeted therapies. To date, no direct KRASG12D inhibitors have received global regulatory approval, highlighting the pressing demand for effective agents. In KRASG12D, the G12D substitution reduces RAS-bound GTP hydrolysis rate by ~2-fold compared to wild-type KRAS (and even more relative to KRASG12C), resulting in a higher proportion of KRASG12D existing in the GTP-bound conformation within cancer cells. This makes the “ON” state the dominant, therapeutically relevant form driving oncogenesis. Inhibiting this active, GTP-bound pool directly disrupts the core signaling activity, potentially yielding greater efficacy than targeting the transient “OFF” state. This mechanism supports targeting the GTP-bound conformation as a strategy with high clinical benefit potential. Emerging KRASG12D inhibitors target OFF, ON, or both states. Phase 1/1b data show ON-state inhibitor RMC-9805 and ON/OFF inhibitor VS-7375 (GFH375) have comparable objective response rates (ORR) and disease control rates (DCR) in NSCLC at their respective recommended Phase 2 doses (RP2D). In PDAC, VS-7375 had marginally higher ORR/DCR (52%/100% vs. 30%/80% for RMC-9805), but RMC-9805 had superior safety: low dose modification rates, no grade 4/5 TRAEs (predominantly grade 1 toxicities), and no DLTs. VS-7375 had a ~4-fold higher discontinuation rate, with 27.5% of patients experiencing grade 3/4 TRAEs. To address these challenges, Rongchang Pharmaceuticals has developed RCZY-869, a highly potent, selective, and orally bioavailable covalent tri-complex inhibitor that specifically targets the GTP-bound (ON) state of KRASG12D. It engages cyclophilin A (CypA) to form a stable ternary complex with KRASG12D(ON), blocking downstream effectors and suppressing MAPK signaling. RCZY-869 exhibits significantly greater in vitro antiproliferative activity than RMC-9805 across KRASG12D-mutant cell lines, favorable ADME properties, and superior oral PK in preclinical species. In KRASG12D xenograft models, it delivers dose-dependent antitumor effects at well-tolerated doses, achieving tumor growth inhibition (TGI) comparable to RMC-9805 but at substantially lower exposures. These findings position RCZY-869 as a novel ON-state-selective KRASG12D inhibitor with compelling preclinical potency and efficacy. Ongoing characterization advances its candidate package to support clinical development.", "source_company": "Rongchang Pharmaceuticals, Ltd.", "source_org_type": "公司", "row_number": 260, "target_meta": "KRAS G12D", "MOA_meta": "抑制剂"}, {"drug_name": "a bispecific ADC targeting Nectin-4 and HER2", "company": "Earendil Labs", "org_type": "公司", "target": "Nectin-4 and HER2", "modality": "bispecific ADC", "importance_level": "高", "total_score": 79.5, "institution_score": 85, "track_score": 90, "milestone_score": 60, "field_heat_score": 85, "bonus_score": 3, "brief_reason": "药物为靶向Nectin-4和HER2的双特异性ADC，Nectin-4在多种实体瘤高表达且已有EV获批先例，双靶点设计提升共表达肿瘤的内吞和疗效。机构为AI驱动的头部新兴biotech，近期获巨额融资并与Sanofi、WuXi合作，赛道热门但仍处preclinical阶段。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9672", "id": "91XM_5wBX1NQZOEH-LC5", "source_drug_name": "a bispecific ADC targeting Nectin-4 and HER2", "title": "A novel bispecific ADC targeting Nectin-4 and HER2 demonstrates superior and broad antitumor efficacy in preclinical models", "abstract_text": "Recently Nectin-4 has emerged as a prominent oncological target due to its high expression across various solid tumors (e.g., urothelial carcinoma, breast cancer, lung cancer, and pancreatic cancer) with restricted expression in normal adult tissues. The clinical significance of Nectin-4 is underscored by the FDA's approval of enfortumab vedotin (EV) for the treatment of urothelial carcinoma. Several novel therapeutic modalities targeting Nectin-4 are under active investigation for cancer therapies. Herein, we describe the design and development of a panel of bispecific antibodies (bsAbs) targeting both Nectin-4 and HER2. Each individual binding arms of the bsAb were engineered and fine-tuned to moderate affinity in order to instill an avidity-driven binding to cells co-expressing both target antigens. The formats of bsAbs were further optimized for favorable developability. The lead BsAb was subsequently conjugated with varieties of cytotoxic payloads to generate bispecific ADC candidates. Several assays were established to exam cell-binding, internalization, and biological activities of the bispecific ADC in cancer cells that express either one or both of the tumor antigens. Internalization assays demonstrated that the BsAbs were endocytosed in tumor cells co-expressing Nectin-4 and HER2 more efficiently than monoclonal antibodies against Nectin-4 or HER2. The antitumor activity of the bispecific ADCs in multiple CDX mouse models were assessed. The lead bsADC demonstrated potent efficacy in CDX models with varying target expression levels, indicating its potential for a broad anti-tumor spectrum for UC and other solid tumors with dual HER2/Nectin-4 antigen expression.", "source_company": "Earendil Labs", "source_org_type": "公司", "row_number": 301, "target_meta": "NECTIN4,HER2", "MOA_meta": "抗体偶联药物"}, {"drug_name": "SDF-061390E", "company": "Synthetic Design Lab", "org_type": "其他", "target": "BCMA, GPRC5D, CD38", "modality": "ADC", "importance_level": "高", "total_score": 79.5, "institution_score": 75, "track_score": 90, "milestone_score": 70, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "SDF-061390E为多价多特异性ADC平台Synthbody™的首款分子，靶向BCMA/GPRC5D/CD38组合实现合成逻辑门控靶向，多靶点协同显著提升内化及 potency（>30x和>80x），优于单靶点对照。机构由Genentech前高管创立虽为早期biotech但背景强，ADC+多靶点逻辑门控赛道极热，前临床数据强劲且具新机制亮点。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6307", "id": "A1XM_5wBX1NQZOEH-LG5", "source_drug_name": "SDF-061390E", "title": "Synthbody™- A novel multivalent multispecific antibody drug conjugate platform demonstrates combinatorial logic-gated “synthetic” targeting of cancer antigens with log order enhanced internalization and potency", "abstract_text": "Antibody Drug Conjugates (ADCs), such as trastuzumab deruxtecan, achieve complete responses >20% and duration of response >30 months in patients with metastatic Her2+ breast cancer1. However, other mono/bi-specific ADCs have not achieved similar clinical benefit, likely due to the 10-100x higher expression levels of Her2 vs other ADC targets, as well as known heterogeneity of target expression, down-regulation of targets in response to treatment and in some cases, competition from soluble target release.\nTo address these fundamental limitations, we developed a novel class of engineered multifunctional multivalent multispecific therapeutics (SynthbodyTM) that enable targeting of combinatorial “synthetic” cancer targets incorporating 6-12 tumor antigen binding domains. This replicates Her2-like high expression and specificity for ADC therapeutics in most tumors without high levels of expression of a single specific tumor antigen.\nWe engineered an initial human multiple myeloma targeting SynthbodyTM, referred to as SDF-061390E, that includes affinity-tuned binders for BCMA, GPRC5D and CD38. SDF-061390E (and SDF-061390E-MMAF) demonstrates >30x greater internalization and >80x greater potency when compared, respectively, with the BCMA-targeting antibody Belantamab and Belantamab mafodotin in human myeloma cells. Enhanced internalization and potency are similarly observed when compared against matched mono/bi-specific controls. Additionally, SDF-061390E can bind human myeloma cell lines with both high and low expression of each of the three targets and effectively eliminate low-BCMA expressing cancer cells in ADC killing assays. Further, SDF-061390E can evade impact of soluble BCMA at clinically relevant and higher concentrations, in contrast to belantamab. Similar results are also observed with a NHL targeting SynthbodyTM, supporting the broad applicability.\nDue to biophysical characteristics that can be controlled in the design of Synthbody™ constructs, we generate emergent properties, including conditional activity determined by the geometry and biophysical relationships between the cancer cell antigens, epitopes, and the SynthbodyTM. This architecture enables the Synthbody™ ADCs to include AND BETTER logic-gated control, layered with AND safety gates and MULTIPLIER functions, yielding synergistic multifunctional activity absent from ADCs. Optimized Synthbody™ constructs show excellent production in CHO cells, developability and IgG-like PK in vivo.\nThe novel Synthbody™ platform demonstrates broad utility as ADC and biologic therapeutics, with capabilities for coordinated targeting, advanced logic-gated control and multifunctional action that may complement or ultimately replace current IgG-based biologics.\n1 Cortes et al. Nat Med 2024", "source_company": "Synthetic Design Lab", "source_org_type": "其他", "row_number": 313, "target_meta": "BCMA,GPRC5D,CD38", "MOA_meta": "抗体偶联药物"}, {"drug_name": "Pan-GATA molecular glues", "company": "Novartis Institutes For Biomedical Research, Inc.", "org_type": "公司", "target": "GATA3", "modality": "molecular glues", "importance_level": "高", "total_score": 79.5, "institution_score": 95, "track_score": 90, "milestone_score": 40, "field_heat_score": 85, "bonus_score": 3, "brief_reason": "Pan-GATA molecular glues靶向降解ER+乳腺癌中关键转录因子GATA3，属于热门的分子胶降解剂赛道且由Novartis顶级机构开发；因摘要禁运仅体现preclinical概念阶段，里程碑信息有限故综合评分较高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11416", "id": "BFXM_5wBX1NQZOEH-LG5", "source_drug_name": "Pan-GATA molecular glues", "title": "Pan-GATA molecular glues as novel tools for targeted degradation of GATA3in ER+breast cancers", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Novartis Institutes For Biomedical Research, Inc.", "source_org_type": "公司", "row_number": 314, "target_meta": "GATA3", "MOA_meta": "分子胶"}, {"drug_name": "DLL3 x B7H3 bispecific ADC", "company": "GeneQuantum Healthcare (Suzhou) Co., Ltd.", "org_type": "公司", "target": "DLL3 & B7H3", "modality": "bispecific ADC", "importance_level": "高", "total_score": 79.5, "institution_score": 75, "track_score": 90, "milestone_score": 70, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "药物为靶向DLL3和B7H3的双特异性ADC，旨在克服SCLC肿瘤异质性并提升难治亚型疗效；GeneQuantum作为国内专注ADC酶法位点特异性偶联技术的头部biotech，赛道热门且preclinical数据优于临床基准单抗ADC，综合潜力较高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5378", "id": "L1XM_5wBX1NQZOEH-LG5", "source_drug_name": "DLL3 x B7H3 bispecific ADC", "title": "Novel DLL3 x B7H3 bispecific ADC demonstrated superior efficacy in preclinical studies", "abstract_text": "Background: Small Cell Lung Cancer (SCLC) is a highly aggressive neuroendocrine carcinoma accounting for approximately 15% of all lung cancer diagnoses. It is characterized by rapid proliferation, early metastasis, and a dismal prognosis, with a 5-year survival rate of only 3% for patients with metastatic disease. Research over the past decade has revealed significant molecular heterogeneity in SCLC, leading to a classification into four major subtypes based on distinct transcriptional signatures: there are defined by the expression of specific transcription factors—ASCL1 high (SCLC-A), NEUROD1 high (SCLC-N), and POU2F3 high (SCLC-P)—and the fourth, SCLC-I, is characterized by low expression of these three factors. Notably, the SCLC-P subtype has been associated with inferior outcomes following chemo-immunotherapy, suggesting it may represent a more treatment-resistant variant. This high heterogeneity is likely a key driver of therapeutic resistance. DLL3, an inhibitory ligand of the Notch pathway, is overexpressed in up to 85% of SCLC tumors and varies significantly across SCLC subtypes, while its expression is negligible in normal tissues. B7H3, a type I transmembrane protein belonging to the B7 immune checkpoint family, is another promising target. It is expressed at low levels in normal tissues but is highly and homogeneously overexpressed across all SCLC subtypes, as well as in other solid tumors.\nMethods: To address tumor heterogeneity in SCLC and improve responses for treatment-resistant patients—particularly those with the SCLC-P subtype—we pursued a rational design of a bispecific antibody-drug conjugate (ADC) targeting both DLL3 and B7H3. We engineered a diverse library of bispecific antibodies with varying sequence combinations and structural formats, which were then conjugated to diverse linker-topoisomerase 1 inhibitor (Top1i) payloads. Through a systematic screening campaign involving comprehensive in vitro and in vivo evaluations, we successfully identified a superior lead bispecific ADC candidate.\nResults: The lead bispecific antibody exhibited potent cellular internalization in vitro, while the bispecific ADC demonstrated concentration-dependent and target-specific cytotoxicity in antigen-positive cells. In vivo, across multiple patient-derived xenograft (PDX) models, the lead bispecific ADC exhibited robust and sustained antitumor activity, outperforming both clinical-stage monospecific ADC benchmarks and its parental monospecific ADC. Notably, in refractory SCLC-P PDX models, it maintained superior efficacy compared to clinical monospecific ADC benchmarks. These results support a synergistic mechanism of action conferred by the bispecific ADC.\nConclusions: In conclusion, the next-generation bispecific ADC holds great potential to overcome SCLC heterogeneity and improve outcomes for treatment-resistant patients.", "source_company": "GeneQuantum Healthcare (Suzhou) Co., Ltd.", "source_org_type": "公司", "row_number": 342, "target_meta": "DLL3,CD276", "MOA_meta": "抗体偶联药物"}, {"drug_name": "CKAP2 small molecule modulator", "company": "Soley Therapeutics", "org_type": "公司", "target": "CKAP2", "modality": "inhibitor", "importance_level": "高", "total_score": 79.5, "institution_score": 75, "track_score": 85, "milestone_score": 80, "field_heat_score": 80, "bonus_score": 8, "brief_reason": "靶向此前被认为不可成药的CKAP2（微管生长关键因子），通过小分子调控下游FAK-ERK2通路实现抗肿瘤活性；Soley Therapeutics作为获2亿美元C轮融资的头部新兴biotech，平台驱动first-in-class项目，preclinical数据强（多模型体内79%抑瘤、机制验证），赛道新颖具突破性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8878", "id": "O1XM_5wBX1NQZOEH-LG5", "source_drug_name": "CKAP2 small molecule modulator", "title": "CKAP2 modulation with a novel small molecule results in excellent in-vitro and in-vivo anti tumor activity", "abstract_text": "Cytoskeleton-Associated Protein 2 (CKAP2) is an intrinsically disordered protein, considered undruggable, and the most potent microtubule growth factor identified to date. It is associated with malignant progression, modulating multiple cancer-associated processes including cell proliferation, migration, metastasis and angiogenesis, and may act as a functional oncogene by targeting FAK-ERK2 signaling pathway. CKAP2 has been reported to be an important prognostic marker and potential therapeutic target in certain cancers (e.g. non-small cell lung cancer). We have discovered and are developing an oral CKAP2 small molecule modulator as a potential treatment for cancer. Bioinformatics analysis of a 300 tumor cell line panel treated with the CKAP2 modulator demonstrated a strong correlation between CKAP2 protein abundance and drug sensitivity across cancer types, with large B cell lymphoma and acute myeloid leukemia showing the highest drug sensitivity. Additionally, analysis in the TCGA cohort indicated that CKAP2 RNA expression was significantly elevated in patient tumors compared to normal tissues and strongly correlated with their predicted sensitivity to the CKAP2 modulator. Protein array analysis revealed that proteins associated with predicted sensitivity are involved in downstream pathways of CKAP2 such as cell migration and focal adhesion signaling. Functional studies indicated down-stream pathways of CKAP2 to be affected upon treatment. Treatment of cells with either the CKAP2 modulator, or with CKAP2 targeting siRNA, similarly decreased FAK protein level, reduced migration and diminished cell viability/count. Immunofluorescence-based assays confirmed altered CKAP2 phenotype and disruption of microtubule network upon treatment, resulting in G2/M cell cycle arrest. Furthermore, CKAP2 modulation significantly inhibited angiogenesis in tube formation assays using HUVECs and maintained activity in hypoxia, which is a driver of angiogenesis and associated with resistance to many therapies. In-vivo efficacy was demonstrated in a mouse xenograft model of non-small cell lung cancer and three different models of colon cancer with up to 79% tumor volume reduction noted at the highest dose tested and was well tolerated. In conclusion, we have discovered a first-in-class, oral small molecule which modulates CKAP2 and its downstream pathways indicating very good anti-tumor activity both in-vitro and in-vivo. This novel therapy is being considered as a promising therapeutic candidate for the treatment of CKAP2 expressing cancers.", "source_company": "Soley Therapeutics", "source_org_type": "公司", "row_number": 348, "target_meta": "CKAP2", "MOA_meta": "抑制剂"}, {"drug_name": "BCN-OH", "company": "WuXi XDC", "org_type": "公司", "target": "未披露", "modality": "other", "importance_level": "高", "total_score": 79.5, "institution_score": 85, "track_score": 80, "milestone_score": 65, "field_heat_score": 85, "bonus_score": 3, "brief_reason": "BCN-OH 是 WuXi XDC 创新 ADC payload-linker 平台中关键的 strained alkyne 连接原料，用于 azido-sugar 位点特异性偶联技术，具有优异偶联效率和治疗指数，但本身为不稳定起始物料。WuXi XDC 作为 ADC/CRDMO 领域领先机构，开发此 HPLC 方法解决其不稳定问题，支持高质量制造，赛道热度高但非药物实体且无临床里程碑。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5374", "id": "P1XM_5wBX1NQZOEH-LG5", "source_drug_name": "BCN-OH", "title": "Method development of purity and assay HPLC method for unstable antibody-drug conjugate linker regulated starting material BCN-OH", "abstract_text": "BCN-OH is a critical raw material in an innovative payload-linker platform utilizing azido-sugar site-specific conjugation technology, which offers superior conjugation efficiency and therapeutic index. However, BCN-OH exhibits extreme instability, with solution stability of less than one hour and high susceptibility to oxidation upon air exposure. These characteristics pose significant challenges for impurity profiling and specification setting during manufacturing. To address this, we aimed to develop a robust and reproducible HPLC method capable of accurately identifying and characterizing related substances in BCN-OH, ensuring reliable quality control and regulatory compliance. Through systematic optimization of chromatographic conditions—including column selection, temperature, mobile phase composition, sample diluents, and gradient profiles, the method achieved baseline separation of five specified impurities and resolved the main peak from its isomer. Incorporation of BHT as an antioxidant extended BCN-OH solution stability from under one hour to 24 hours, greatly improving operational feasibility. Additional measures, such as nitrogen storage and glove box handling, further minimized oxidation risk. The validated method demonstrated robustness, intermediate precision, and suitability for PPQ and routine QC, providing essential data for impurity specification setting and ensuring consistent quality of this highly unstable payload-linker intermediate.", "source_company": "WuXi XDC", "source_org_type": "公司", "row_number": 352, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "site-specific dual-payload ADCs (dpADCs) co-delivering TOPO1i and proprietary DDR inhibitors", "company": "Sutro Biopharma Inc", "org_type": "公司", "target": "未披露", "modality": "ADC", "importance_level": "高", "total_score": 79.5, "institution_score": 75, "track_score": 95, "milestone_score": 60, "field_heat_score": 85, "bonus_score": 8, "brief_reason": "该药物为Sutro的site-specific dual-payload ADC，同时递送TOPO1i和专有DDRi（PARPi或ATRi），通过合成致死机制增强疗效并克服TOPO1i耐药。Sutro作为专注next-gen ADC的国外头部biotech平台公司，dual-payload+热门payload组合赛道极热，但仍处preclinical阶段，亮点在于新机制克服抵抗和潜在更好TI。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5417", "id": "IFXM_5wBX1NQZOEH-LK6", "source_drug_name": "site-specific dual-payload ADCs (dpADCs) co-delivering TOPO1i and proprietary DDR inhibitors", "title": "Sutro’s site-specific dual-payload ADCs combining TOPO1i and DNA damage response inhibitors to enhance efficacy, overcome resistance, and improve safety", "abstract_text": "Antibody-drug conjugates (ADCs) have demonstrated transformative potential in oncology, but enhancing efficacy of ADC against low-antigen and heterogeneous tumors while overcoming resistance and maintaining safety remain a major challenge. Resistance to single-payload ADCs, particularly TOPO1i based ADCs, is often driven by payload-specific mechanisms such as enhanced DNA repair or upregulation of drug efflux pumps, limiting sustained clinical responses. Sequential administration of TOPO1i ADCs frequently fails to restore efficacy, underscoring the need for novel, multi mechanistic strategies. Topoisomerase I inhibitors (TOPO1i) induce DNA breaks that collapse replication forks, but their efficacy is constrained by rapid repair via PARP and ATR dependent pathways. DNA damage response inhibitors (DDRi), such as PARPi and ATRi, block these repairs, restoring TOPO1i sensitivity in resistant, SLFN11-deficient, or repair-proficient tumors. This combination enforces checkpoint failure and prevents fork repair, providing a strong rationale for synergistic antitumor activity while limiting the development and progression of acquired resistance. Although combining TOPO1 inhibition with DDRi has a strong mechanistic rationale, clinical application is constrained by overlapping and non-overlapping toxicities. To overcome these challenges, we developed site-specific dual-payload ADCs (dpADCs) to co-deliver TOPO1i and proprietary DDR inhibitors, including PARPi or ATRi that are not substrates for drug efflux pumps. This strategy leverages synthetic lethality by pairing TOPO1i-induced DNA damage with DDR blockade, selectively enhancing cytotoxicity in target-antigen expressing tumor cells. Key challenges in developing TOPO1i × DDRi dpADCs include optimizing DDRi properties suitable for ADC delivery, selecting payload ratios, maintaining conjugate homogeneity, ensuring linker stability, and mitigating systemic toxicity. By leveraging Sutro’s cell-free expression platform, precise dual-conjugation technology, and hydrophilic tumor-selective β-glucuronidase cleavable linkers, we engineered homogeneous, site-specific dpADCs with tunable drug-to-antibody ratios (DARs). These design features enhance solubility, stability, and pharmacokinetics while preserving payload synergy. We demonstrate that Sutro’s site-specific TOPO1i × DDRi dual-payload ADCs (dpADCs) exhibit superior anti-tumor activity compared to single-payload ADCs, including in models resistant to TOPO1i ADCs. The targeted co-delivery of TOPO1i and DDRi has the potential to minimize off-target toxicity typically associated with systemic DDR inhibition, thereby broadening the therapeutic window and streamlining preclinical and clinical development compared to separate combination regimens.", "source_company": "Sutro Biopharma Inc", "source_org_type": "公司", "row_number": 511, "target_meta": "not available", "MOA_meta": "抗体偶联药物"}, {"drug_name": "payload-recycling ADC (PR-ADC)", "company": "RemeGen Co., Ltd.", "org_type": "公司", "target": "MSLN (mesothelin)", "modality": "ADC", "importance_level": "高", "total_score": 79.5, "institution_score": 75, "track_score": 90, "milestone_score": 70, "field_heat_score": 85, "bonus_score": 8, "brief_reason": "PR-ADC为靶向MSLN的创新型ADC，通过双特异性设计回收游离MMAE payload以降低毒性、提升安全性及疗效窗口。RemeGen作为国内头部ADC公司（有已上市ADC RC48），该平台技术具显著创新亮点和临床潜力，赛道热度高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5347", "id": "slXM_5wBX1NQZOEH-LK6", "source_drug_name": "payload-recycling ADC (PR-ADC)", "title": "Payload-recycling ADCs (PR-ADCs): A novel ADC platform for reducing free-payload toxicity and enhancing therapeutic index", "abstract_text": "Background: Antibody-drug conjugates (ADCs) have emerged as an important class of cancer therapeutics in clinical application. Many ADC drugs, however, failed during clinical studies due to excessive toxicity. Even approved ADC drugs also often face challenges in balancing clinical efficacy and safety. A major cause of ADC toxicity is due to free-payload (small molecule toxin) released from ADC drug into circulation. Free-payload often appears rapidly in plasma after ADC administration which causes systemic toxicity. To overcome ADC toxicity caused by free-payload, we have developed a novel technology, payload-recycling ADC (PR-ADC), that allows ADC drugs to re-capture, or recycle, small molecule toxin in circulation, thus reducing free-drug concentration in plasma.\nMethods: To develop PR-ADC technology, we first generated a high affinity anti-MMAE monoclonal antibody through hybridoma screening. This anti-MMAE antibody exhibits exceptional specificity to free-MMAE with no detectable cross-reactivity to linker-MMAE or conjugated MMAE. Then an anti-mesothelin (MSLN) single domain antibody was attached to the anti-MMAE antibody to create a bispecific antibody that can simultaneously bind to both tumor antigen MSLN and free-MMAE. This bispecific antibody was then conjugated with MMAE to become the PR-ADC molecule which is basically a mesothelin-directing ADC with an additional ability to capture free-MMAE.\nResults: This PR-ADC can effectively kill MSLN-expressing tumor cells in vitro in a potency similar to or even higher than a conventional MSLN-targeting ADC. On the other hand, this PR-ADC can prevent MMAE-induced cytotoxicity in cell-protection assays, highlighting its ability to effectively shield normal cells or tissues from free-MMAE-induced damage, thus increasing safety of ADC drugs. In vivo, this PR-ADC molecule, compared to conventional ADC, significantly reduced free-MMAE concentration in serum after administrated in mice or rats. In toxicity studies in rats, the PR-ADC significantly improved safety profile, showing larger therapeutic window than the conventional ADC. The increased safety profile of PR-ADC in vivo was further supported by favorable tissue distribution, drug metabolism and pharmacokinetics (DMPK) profiles. In xenograft tumor model studies, the MSLN-targeting PR-ADC achieved robust tumor growth inhibition, outperforming the conventional ADC.\nConclusions: The PR-ADC platform improves ADC safety by minimizing free payload-mediated toxicity while maintaining or enhancing anti-tumor efficacy. By enabling active payload recapture, PR-ADCs may support higher clinical dosing, increased effective DAR through captured payload, and an overall superior therapeutic index. This technology represents a promising next-generation strategy for advancing ADC development.", "source_company": "RemeGen Co., Ltd.\nRemeGen Co., Ltd\nRemeGen Biosciences", "source_org_type": "公司", "row_number": 603, "target_meta": "MSLN", "MOA_meta": "抗体偶联药物"}, {"drug_name": "a bispecific ADC (bsADC)", "company": "VERAXA Biotech GmbH", "org_type": "公司", "target": "未披露", "modality": "bispecific ADC", "importance_level": "高", "total_score": 79.5, "institution_score": 75, "track_score": 90, "milestone_score": 70, "field_heat_score": 85, "bonus_score": 3, "brief_reason": "bsADC采用双靶点AND-gate逻辑门设计结合稳定亲水连接子和PBD prodrug，实现肿瘤高度选择性杀伤，靶点为未披露的双TAA组合。VERAXA为专注ADC/bsADC创新的国外头部biotech（已推进至IND-enabling并有临床管线），热门双特异性ADC赛道+强劲preclinical数据（体内外优异窗口、安全性）驱动高分。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4319", "id": "4FXM_5wBX1NQZOEH-LK6", "source_drug_name": "a bispecific ADC (bsADC)", "title": "An avidity-driven, dual-targeting ADC with superior tumor selectivity for the treatment of solid tumors", "abstract_text": "Background\nAntibody drug conjugates (ADCs) represent one of the most promising therapeutic modalities in recent years. However, the full therapeutic potential of ADCs is hampered because many tumor antigens are also expressed in healthy tissues, causing on-target, off-tumor toxicities. Other toxicities are caused by off-target uptake of ADCs in healthy cells or by systemic payload exposure as consequence of unstable conjugation. These issues have restricted a successful implementation of highly potent payloads such as pyrrolobenzodiazepine dimers (PBD).\nMethod\nWe developed a bispecific ADC (bsADC) which requires the simultaneous binding to two tumor-associated antigens (TAAs) to mediate cytotoxic activity (AND-gate approach). Co-expression of the TAAs is only found in tumor cells. Cell killing is therefore restricted to tumor cells. Healthy cells, which express only one of the TAAs, are spared. Our lead candidate comprises a bispecific antibody linked to a PBD prodrug at a DAR of 2 via a tumor-selective glucuronide linker using our proprietary site-specific, click-based glycan conjugation platform, which minimizes off-target toxicity by two mechanisms: first, using a highly stable linker, the payload is not released in circulation but only inside cells expressing both targets; second, hydrophilic chemistry prevents target-independent uptake.\nResults\nWe identified a TAA pair that is highly co-expressed in various solid tumors including TNBC and NSCLC, while co-expression in healthy tissues is limited. It therefore represents a promising target combination for the development of an AND-gated bsADC with enhanced tumor-selectivity. Our lead candidate makes use of a pronounced avidity binding due to low monovalent affinities for both targets. This translates into superior internalization as well as potent killing of tumor cell lines expressing both targets in comparison to healthy cells expressing one target, resulting in an increased therapeutic window. In co-culture assays, the bsADC induced bystander killing of target-negative cells, indicating the bsADC should be efficacious in tumors where co-expression of both targets is not 100% penetrant. In vivo, our candidate dose-dependently reduced the tumor burden in mice bearing cell line-derived xenograft (CDX) models of breast cancer. In addition, the bsADC was well-tolerated up to high dose levels in mice and showed high stability in vitro and in vivo.\nConclusion\nBy combining an AND-gated, dual-targeting approach with our hydrophilic, highly tumor-selective, and stable ADC conjugation platform, we have generated a bsADC with superior tumor specificity. This enables the application of a potent PBD prodrug for highly efficient anti-tumor activity. Our lead bsADC for the treatment of lung and breast cancers has entered formal preclinical development and IND-enabling studies.", "source_company": "VERAXA Biotech GmbH", "source_org_type": "公司", "row_number": 632, "target_meta": "not available", "MOA_meta": "抗体偶联药物"}, {"drug_name": "EXP012", "company": "Excalipoint Therapeutics Inc.", "org_type": "公司", "target": "CDH17", "modality": "tri-specific T cell engager", "importance_level": "高", "total_score": 79.5, "institution_score": 75, "track_score": 90, "milestone_score": 70, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "EXP012为靶向CDH17的下一代三特异性T细胞衔接器（CDH17×CD3×4-1BB），通过整合4-1BB共刺激显著增强对冷肿瘤的T细胞激活和持久抗肿瘤活性。公司为国内新兴头部biotech，获巨额种子轮融资且快速推进管线，三特异性TCE+固瘤热门靶点+创新共刺激机制具高热度和潜力。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4546", "id": "hVXM_5wBX1NQZOEH-LO6", "source_drug_name": "EXP012", "title": "A next-generation tri-specific T cell engager targeting CDH17 with 4-1BB co-stimulation for the treatment of gastrointestinal cancers", "abstract_text": "Background: Cadherin-17 (CDH17), a membranous cell adhesion protein, is highly expressed in gastrointestinal (GI) cancers, particularly in colorectal cancer. In normal intestine tissue, CDH17 is restricted to the lateral side of the epithelial cells and remains largely inaccessible to antibody, making it a promising therapeutic target for GI malignancies. Our platform has demonstrated that incorporating 4-1BB costimulation can effectively convert immunologically \"cold\" tumors into \"hot\". This transformation is achieved by enhancing the infiltration of peripheral T cells into the tumor and systemically remodeling the tumor microenvironment. Moreover, this strategy elicits a durable T cell memory response and significantly prolongs survival. Given that GI cancer is a classic \"cold\" tumor, we have developed a novel tri-specific T cell engager (TCE) that targets CDH17 on cancer cells and engages CD3 and 4-1BB on T cells. This TCE is engineered to redirect and enhance T cell responses against CDH17-expressing tumor cells. With a manageable safety profile, this approach holds strong potential to improve clinical outcomes for patients with GI cancers.\nMethods: The in vitro activities of the CDH17-CD3-4-1BB tri-specific TCE were evaluated in both CDH17-positive and -negative tumor cell lines. These assessments included T cell-mediated cytotoxicity, T cell activation, cytokine release and T cell proliferation. In vivo anti-tumor activity was investigated in two models: a humanized syngeneic mice model bearing B16F10-hCDH17 tumors and NCG-MHC-dKO mice with human PBMC bearing Lovo tumors. Cytokine release assay (CRA) was conducted to evaluate potential cytokine storm risk. Additionally, the toxicological profile was assessed in a pilot toxicity study in cynomolgus monkeys.\nResults: CDH17-CD3-4-1BB tri-specific TCE demonstrated CDH17-dependent activation of CD3 and 4-1BB. It effectively induced tumor lysis in multiple CDH17+ tumor cell lines and significantly enhanced T cell activation, cytokine production and T cell proliferation in the presence of CDH17-expressing target cells. In humanized syngeneic tumor mouse model and human PBMC xenograft tumor mouse model, this molecule demonstrated robust tumor growth inhibition and prolonged survival rate. Furthermore, an in vitro CRA indicated lower IL-6 release compared to a clinical benchmark, indicating a more manageable risk of cytokine release syndrome (CRS). In the pilot tox study, no adverse effects were observed in clinical signs and histopathology.\nConclusion: CDH17-CD3-4-1BB tri-specific TCE represents a novel CDH17-targeted T cell engager with potent and durable anti-tumor activity. Collectively, these results underscore its potential as a novel therapeutic agent against GI cancers and support its advancement into clinical development.", "source_company": "Excalipoint Therapeutics Inc.", "source_org_type": "公司", "row_number": 740, "target_meta": "CDH17", "MOA_meta": "其他"}, {"drug_name": "Rebecsinib", "company": "Aspera Biomedicines", "org_type": "biotech", "target": "ADAR1", "modality": "inhibitor", "importance_level": "高", "total_score": 79.5, "institution_score": 75, "track_score": 85, "milestone_score": 80, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "Rebecsinib为靶向ADAR1剪接的小分子抑制剂，可选择性抑制肿瘤干细胞自我更新并减少CD44+和ADAR1+ TNBC细胞，机制新颖且针对癌症干细胞克隆和免疫逃逸。机构为大学衍生biotech公司、已获FDA IND进入临床、赛道为first-in-class ADAR1抑制剂在癌症干细胞领域具高潜力，故综合评分较高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8871", "id": "q1XM_5wBX1NQZOEH-LO6", "source_drug_name": "Rebecsinib", "title": "Therapeutic targeting of ADAR1 p150 splicing activity impairs CD44+ TNBC cell populations in preclinical studies", "abstract_text": "Background: Triple-negative breast cancer (TNBC) remains clinically challenging due to the lack of targeted therapies and the presence of therapy-resistant tumor-propagating cells. CD44 and ADAR1 contribute to TNBC progression and therapeutic resistance. Rebecsinib is a small-molecule inhibitor designed to block splicing-mediated activation of ADAR1 (adenosine deaminase acting on RNA 1). This study evaluates its efficacy in selectively targeting CD44+ and ADAR1+ cells in preclinical humanized TNBC models.\nMethods: MDA-MB-231 TNBC cell line-derived xenograft (CDX) models were established in Rag2-/-γc-/- and NSG-SGM3 mice. MDA-MB-231 ADAR-nanoluciferase-GFP expressing cells enable tracking of ADAR1 activity by IVIS imaging. Engrafted mice received vehicle, Rebecsinib IV (10 mg/kg), or Rebecsinib PO (15mg/kg), twice a week for two weeks. Tumor burden was measured by IVIS and single-cell suspensions from peripheral blood, and tissues (lung, liver, spleen, and bone marrow) were analyzed by flow cytometry to quantify CD44+ and ADAR1+ cells.\nResults: Rebecsinib significantly reduced CD44+ cells in peripheral blood (p < 0.05), lung (p < 0.01), liver (p < 0.01), and spleen (p < 0.05) in Rag2-/-γc-/- models (Student t test). Corresponding decreases in ADAR1+ cells was observed in the lung (p < 0.05), liver (p < 0.01), and spleen (p < 0.01) in NSG-SGM3 mouse models (Student t test). IVIS imaging demonstrated tumor bioluminescence in Rebecsinib-treated groups (p = 0.02, student t test). Combination with Fedratinib further suppressed tumor growth, indicating a synergistic effect (p < 0.05, student t test).\nConclusion: Rebecsinib selectively reduces CD44+ and ADAR1+ TNBC cell populations and inhibits tumor progression in humanized preclinical models. These findings support further evaluation of Rebecsinib alone and in combination, as a targeted therapeutic approach for TNBC.\nKeywords: TNBC, ADAR1, CD44, Rebecsinib, targeted therapy, preclinical models.", "source_company": "University of California San Diego", "source_org_type": "大学", "row_number": 766, "target_meta": "ADAR", "MOA_meta": "抑制剂"}, {"drug_name": "BiTAC-TCE", "company": "VERAXA Biotech GmbH", "org_type": "公司", "target": "未披露", "modality": "TCE", "importance_level": "高", "total_score": 79.5, "institution_score": 75, "track_score": 90, "milestone_score": 70, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "BiTAC-TCE采用AND-gated双靶点条件激活机制的TCE，针对实体瘤实现高肿瘤选择性，靶点未披露但针对结直肠癌和肺癌共表达TAA对。VERAXA为欧洲创新biotech公司，已进入preclinical开发并IND-enabling，赛道为热门TCE新世代安全优化，总分高因平台创新与实体瘤未满足需求。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5103", "id": "flXM_5wBX1NQZOEH-LS6", "source_drug_name": "BiTAC-TCE", "title": "A conditionally-active, dual-targeting TCE with superior tumor selectivity for the treatment of solid tumors", "abstract_text": "Background\nT cell engagers (TCEs) represent a rapidly advancing class of immunotherapies that have demonstrated remarkable clinical efficacy in hematologic malignancies. However, their application in solid tumors remains limited by on-target, off-tumor toxicities resulting from antigen expression in healthy tissues. Moreover, off-target, off-tumor effects can arise from systemic T cell engagement and nonspecific activation, leading to cytokine release syndrome (CRS). To overcome these challenges, we have developed an innovative TCE platform incorporating an AND-gated safety mechanism that enables selective killing of tumor cells while sparing healthy cells.\nMethod\nThe Bi-targeted Tumor-Associated Cytotoxicity (BiTAC) T cell engager builds up on the previously described hemibody concept1 and employs an on-cell assembly mechanism of two complementary compounds to achieve conditional activation. Each compound comprises a tumor-binding domain recognizing a distinct tumor-associated antigen (TAA) and a split T cell-binding moiety. Individually, the compounds do not engage T cells. Productive T cell activation occurs only when both compounds co-bind and accumulate on tumor cells co-expressing the respective antigens, leading to reconstitution of an active CD3 binder. The BiTAC-TCE was optimized for developability, stability, and potent functional activity in both in vitro and in vivo settings.\nResults\nOur bioinformatics pipeline identified a TAA pair highly co-expressed in colorectal and lung cancers. Constitutively active drugs targeting each TAA individually have been tested in humans and revealed target-associated toxicities. An antibody format with favorable manufacturability and developability was subsequently selected. Using in vitro T cell-dependent cellular cytotoxicity (TDCC) assays across multiple cell lines in 2D and 3D cultures, we demonstrate that the combinatorial design of BiTAC-TCE enables T cells to selectively eliminate dual-target-positive tumor cells while sparing single-positive healthy cells. Individual compounds/BiTAC precursors don’t bind T cells and don’t induce TDCC in vitro and in vivo. Furthermore, BiTAC-TCE exhibits strong antitumor efficacy in PBMC-engrafted mice bearing colorectal tumors and displays a favorable pharmacokinetic (PK) profile in preclinical mouse studies.\nConclusion\nOur BiTAC-TCE platform enables precise targeting of solid tumors through TAAs not druggable by current immunotherapies. Both TAAs addressed are broadly expressed but not co-expressed on healthy cells of different tissues, leading to failure of monotargeting T cell engagers in clinical settings. Our lead BiTAC-TCE for the treatment of colorectal and lung cancers has recently entered formal preclinical development and IND-enabling studies.\n1Banaszek, A. et al. Nat Commun 10, 5387 (2019)", "source_company": "VERAXA Biotech GmbH", "source_org_type": "公司", "row_number": 921, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "DLL3×CD3×4-1BB trispecific antibody", "company": "Biocytogen", "org_type": "公司", "target": "DLL3", "modality": "trispecific antibody", "importance_level": "高", "total_score": 79.5, "institution_score": 75, "track_score": 90, "milestone_score": 70, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "靶向DLL3的trispecific T cell engager（CD3×4-1BB共刺激），解决固瘤TCE中T细胞耗竭问题，preclinical模型显示优于benchmark的T细胞持久性、抗肿瘤效力和安全性。Biocytogen作为国内头部biotech平台公司，trispecific+4-1BB co-stimulation在热门DLL3 TCE赛道具创新亮点。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4566", "id": "dZ7ECZ0BZznHJdntvNYd", "source_drug_name": "DLL3×CD3×4-1BB trispecific antibody", "title": "BCG024: A novel DLL3×CD3×4-1BB trispecific T cell engager enhances T cell persistence and functionality in preclinical models", "abstract_text": "Background: CD3-based T cell engagers (TCEs) as powerful therapeutic agents have demonstrated clinical success in both hematologic malignancies and solid tumor indications. One major obstacle to TCE therapies in treating solid tumors is T-cell exhaustion due to conventional TCEs lacking co-stimulatory signaling, limiting their therapeutic durability. To address this challenge, integrating a co-stimulatory signal such as 4-1BB into TCEs could be an attractive approach to enhance T cell function and durability.\nMethods: We developed a trispecific antibody (TriAb) targeting DLL3, CD3, and 4-1BB using a VHH 4-1BB agonist derived from RenNano® mice to achieve tumor antigen-dependent co-stimulation. In vitro assays included repeated stimulation assay and cytotoxicity against DLL3-positive small cell lung cancer (SCLC) cell line. In vivo efficacy and T cell proliferation were evaluated in xenograft mouse models bearing established SCLC tumors. The toxicity study was evaluated in CD3ε×4-1BB humanized mice.\nResults: The DLL3 TriAb demonstrated significantly enhanced T cell proliferation while maintaining high cell viability and cytotoxicity following repeated stimulation. However, the benchmark and bsAb counterparts showed marked reductions in cell viability and activity. In vivo, mice treated with benchmark caused dose-dependent reductions in serum T cell number, whereas those treated with DLL3 TriAb maintained stable T cell populations. That indicated TCE integrated 4-1BB nanobody co-stimulation indeed enhances T cell durability and functionality. In SCLC xenograft models, DLL3 TriAb exhibited robust antitumor efficacy in a monovalent antigen-binding format rather than a bivalent antigen-binding format. Notably, contrasting with non-specific TriAb controls, DLL3 TriAb displayed favorable safety profiles in CD3ε×4-1BB humanized mice even at high doses, with no significant body weight loss or systemic cytokine elevation observed.\nConclusions: Our DLL3×CD3×4-1BB TriAb demonstrates tumor-dependent co-stimulation, enhanced T cell persistence and functionality, further exhibiting superior anti-tumor efficacy in preclinical SCLC model and good safety profiles at high dose. These findings highlight the DLL3 TriAb as a next-generation immunotherapy, offering enhanced T cell functionality and clinical translatability.", "source_company": "Biocytogen", "source_org_type": "公司", "row_number": 926, "target_meta": "DLL3", "MOA_meta": "三特异性抗体"}, {"drug_name": "phosphonate-ADC", "company": "Byondis B.V.", "org_type": "公司", "target": "未披露", "modality": "ADC", "importance_level": "高", "total_score": 79.5, "institution_score": 75, "track_score": 90, "milestone_score": 70, "field_heat_score": 85, "bonus_score": 8, "brief_reason": "该ADC通过递送磷酸酯负载实现肿瘤特异性激活Vγ9Vδ2 γδ T细胞的新型免疫刺激机制，靶点未明确披露但平台兼容多种TAA。Byondis作为专注ADC的欧洲临床阶段biotech公司实力较强，ADC+免疫刺激赛道热度高，前临床数据包括猴子耐受性良好及小鼠模型疗效，具创新亮点。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4286", "id": "EZ7M_5wBZznHJdnt_W7O", "source_drug_name": "phosphonate-ADC", "title": "Phosphonate-antibody-drug conjugates, a novel immunostimulatory class of ADCs driving inside-out activation of Vγ9Vδ2 T cells leading to selective tumor cell killing", "abstract_text": "Gamma delta (γδ) T cells are cytotoxic effectors capable of recognizing and eliminating tumor cells independently of major histocompatibility complex (MHC) presentation. Their presence within tumors correlates with improved clinical outcomes across various cancer types. Vγ9Vδ2 T cells, the predominant γδ subset in human blood, recognize intracellular phosphoantigens (pAgs) through inside-out activation of the butyrophilin (BTN)3A/BTN2A complex. Clinical trials have previously been conducted using aminobisphosphonates or synthetic pAgs, either alone or in combination with low-dose interleukin-2 (IL-2); however, these compounds lack tumor specificity and are limited by a very short plasma half-life in vivo.​ To address the lack of tumor targeting and short half-life, we engineered antibody-drug conjugates (ADCs) that selectively deliver phosphonates to tumor cells, enabling inside-out activation of Vγ9Vδ2 T cells. These phosphonate-ADCs consist of a monoclonal antibody directed against a tumor-associated antigen (TAA), conjugated to a phosphonate payload via a linker that is cleavable by lysosomal proteases. We applied this strategy to various TAA-targeting antibodies, including CD123, CD20, TROP2 and HER2 directed IgG1-based monoclonal antibodies.​ TAA-positive tumor cell lines pretreated with phosphonate-ADCs effectively triggered Vγ9Vδ2 T cell activation through a BTN3A-dependent mechanism. This activation led to robust cytokine secretion, degranulation, and efficient tumor cell lysis. Vγ9Vδ2 T cell activation was successfully replicated with ex vivo patient tumoroids (EVPTs) and autologous peripheral blood mononuclear cells (PBMCs), supporting the translational relevance of this approach. In an acute myeloid leukemia (AML) adoptive transfer mouse model, Vγ9Vδ2 T cells significantly reduced the tumor burden in the presence of the tumor-targeting phosphonate-ADC. In cynomolgus monkeys, the lead phosphonate-ADC candidate displayed excellent tolerability at a single dose of up to 100 mg/kg, with no clinical signs of cytokine release syndrome (CRS). Immunostimulatory phosphonate-ADCs represent a novel strategy for targeted, physiologically relevant activation of Vγ9Vδ2 T cells by delivering phosphonates directly to tumor cells. This modular platform can be combined with virtually any tumor-targeting monoclonal antibody with the possibility to preserve Fcγ receptor-mediated effector functions. The resulting dual mechanism, integrating the antibody’s direct anti-tumor activity with the immune-stimulatory properties of the phosphonate payload, offers a versatile and powerful therapeutic modality. Overall, this platform holds significant promise not only for targeted cancer immunotherapy but also for potential applications in other disease areas.", "source_company": "Byondis B.V.", "source_org_type": "公司", "row_number": 1140, "target_meta": "not available", "MOA_meta": "抗体偶联药物"}, {"drug_name": "CD19-CAR-T cells", "company": "BlueWhale Bio", "org_type": "公司", "target": "CD19", "modality": "CAR", "importance_level": "高", "total_score": 79.5, "institution_score": 75, "track_score": 90, "milestone_score": 70, "field_heat_score": 85, "bonus_score": 3, "brief_reason": "药品为CD19靶向CAR-T细胞，采用非病毒CRISPR敲入方式，由BlueWhale Bio的Synecta T1和Flowfect技术优化制造过程，提高编辑效率和细胞扩增。机构为Carl June团队创办的美国biotech，赛道热门且preclinical数据强劲（>40% KI、>5倍扩增），总分高故评为高重要性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5204", "id": "bZ7M_5wBZznHJdnt_W7P", "source_drug_name": "CD19-CAR-T cells", "title": "Synecta™ T1 cell-derived nanoparticles and Flowfect® continuous flow transfection enhance non-viral engineering efficiency and manufacturing scalability of CD19-directed CAR-T cells for hematologic malignancies", "abstract_text": "Background: Autologous CAR-T cell therapies have transformed outcomes in B-cell lymphomas, leukemias, andother indications, yet manufacturing duration, cost, process variability, and dependence on viralvectors continue to limit broader adoption. Improved processes are essential to deliver moreeffective cell therapies and enable broader adoption. Efficient non-viral gene editing requiresactivation that preserves viability and stem-like phenotypes, unlike CD3/CD28 activators, and adelivery system that achieves high editing efficiency without compromising cell health.BlueWhale Bio’s Synecta™ T1 cell-derived nanoparticles (CDNPs) mimic physiologic APC signalingvia membrane-bound OKT-3, CD86, 4-1BBL, IL-7, and IL-15/IL-15RA. Kytopen’s Flowfect Tx®continuous flow cell engineering technology maximizes yields of engineered cells, whileprocessing hundreds of billions of cells in minutes. Here we present the synergies of thesetechnologies to enhance CRISPR-mediated knock-in (KI) of a CD19-CAR at the TRAC locus.\nMethods: Primary healthy donor (HD) human T cells were activated for 2-3 days with Synecta T1 orcomparator activation technologies and then gene-edited using Flowfect Tx® platform to deliverCas9/sgRNA RNP and a CD19-CAR HDR template. KI and knock-out (KO) efficiency, viability,activation, CD4/CD8 ratio, and expansion were quantified through Day 8. Parallel experimentsevaluated Synecta T1 activation immediately after Flowfect Tx transfection in naïve T cells.\nResults: Synecta T1 induced >90% CD69⁺CD25⁺ activation while preserving CD3 expression. By Day 8, Tcells activated with Synecta and transfected Flowfect Tx® platform achieved >40% CD19-CAR KIand >90% TRAC KO, exceeding comparator activation technologies (<25% KI) and improving bothKI and KO efficiencies. Synecta T1 supported >80% viability and >5-fold expansion, yielding thehighest CAR-positive cell numbers, while maintaining a favorable CD4/CD8 profile. In the naïveworkflow, delivering RNP with a nanoplasmid HDR donor first and then activating with SynectaT1 increased KI-positive cells and expansion compared with unstimulated control, producingmarkedly higher CAR⁺ output.\nConclusions: Synecta T1 and Flowfect Tx® platform enable efficient non-viral genome editing and rapidexpansion, supporting a streamlined, non-viral manufacturing approach for CD19-CAR-T cells. Byimproving KI and KO efficiency, Synecta T1 enhances CRISPR-based editing and supports targetedCAR insertion under endogenous promoters. Together, these technologies deliver a scalable\nworkflow that achieves effective therapeutic doses quickly while preserving cell fitness. Futurestudies will evaluate activation strategies aligned with Day-2 or Day-0/1 Flowfect Tx® transfection.", "source_company": "BlueWhale Bio", "source_org_type": "公司", "row_number": 1197, "target_meta": "CD19", "MOA_meta": "其他"}, {"drug_name": "SCR-M030", "company": "Simcere Zaiming Pharmaceutical Co, Ltd.", "org_type": "公司", "target": "PSMA and STEAP1", "modality": "TCE", "importance_level": "高", "total_score": 79.5, "institution_score": 75, "track_score": 90, "milestone_score": 70, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "SCR-M030为首创三特异性T细胞衔接器(TCE)，同时靶向PSMA和STEAP1，针对mCRPC中抗原异质性问题，机制创新且体外/体内优于单靶点对照。Simcere Zaiming作为国内头部创新药企(先声旗下肿瘤子公司)，赛道为热门TCE+前列腺癌双靶点，preclinical数据强劲包括优于AMG509类似物且药代良好，故综合评分较高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5755", "id": "IFXM_5wBX1NQZOEH-LG5", "source_drug_name": "SCR-M030", "title": "SCR-M030, an innovative and potential first-in-class trispecific T cell engager targeting PSMA and STEAP1 for mCRPC", "abstract_text": "Metastatic castration-resistant prostate cancer (mCRPC) represents a highly aggressive and incurable disease, with limited therapeutic options and a dismal prognosis. Among the most promising molecular targets, prostate-specific membrane antigen (PSMA) and six-transmembrane epithelial antigen of the prostate 1 (STEAP1) are both markedly overexpressed in mCRPC, and their expression levels correlate positively with tumor aggressiveness and resistance to androgen-deprivation therapy. Notably, PSMA exhibits significant inter- and intratumoral heterogeneity, a factor that may underlie the heterogeneous clinical responses observed with PSMA-directed agents. In contrast, STEAP1 demonstrates a more uniform distribution across malignant cells, and its expression pattern partially complements that of PSMA in a subset of patients. Leveraging the complementary expression of STEAP1 and PSMA, we generated a first-in-class trispecific T-cell engager (TCE), SCR-M030, that concomitantly binds STEAP1 with high affinity, PSMA with moderate affinity, and CD3 with deliberately attenuated affinity. This avidity-optimized architecture drives preferential docking to double-positive tumor cells, conferring a marked binding advantage over single-target engagement. Functionally, SCR-M030 outperformed PSMA-CD3 and STEAP1-CD3 bispecific controls in vitro, eliciting superior lysis of medium-to-low antigen-expressing tumor cells while releasing minimal cytokines in target-negative conditions, forecasting a reduced risk of CRS. In PBMC-reconstituted prostate cancer xenograft mouse models, SCR-M030 demonstrated specific, dose-dependent antitumor activity. Notably, in the 22RV1 model, SCR-M030 exhibited more potent tumor suppression than the AMG509 analog. Finally, rat pharmacokinetic profiling revealed a long plasma half-life and full compatibility with both intravenous and subcutaneous dosing routes, supporting flexible clinical administration. In conclusion, the novel trispecific TCE SCR-M030 is a strategically designed therapy that demonstrates potent efficacy against challenging low-expression tumors by simultaneously targeting PSMA and STEAP1 with differential affinity. Its robust in vivo performance, favorable pharmacokinetics, and superiority over a relevant comparator underscore its strong potential as a next-generation therapeutic for prostate cancer.", "source_company": "Simcere Zaiming Pharmaceutical Co, Ltd.", "source_org_type": "公司", "row_number": 1239, "target_meta": "PSMA,STEAP1", "MOA_meta": "其他"}, {"drug_name": "ZE98-0277", "company": "Expert Systems, Inc", "org_type": "公司", "target": "KRAS G12D", "modality": "inhibitor", "importance_level": "高", "total_score": 79.5, "institution_score": 65, "track_score": 95, "milestone_score": 75, "field_heat_score": 90, "bonus_score": 3, "brief_reason": "ZE98-0277为口服非共价KRAS G12D小分子抑制剂，IC50 6.3 nM，在多株异种移植模型中有效肿瘤抑制，展示良好成药性与安全性。机构为AI驱动的早期药物加速器公司，非头部MNC或biotech但具创新平台；KRAS G12D为当前最热靶点之一，preclinical数据扎实，综合热度高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6433", "id": "j57M_5wBZznHJdnt_W3O", "source_drug_name": "ZE98-0277", "title": "Discovery and preclinical evaluation of a potent, orally bioavailable, highly selective, small molecule non-covalent KRAS[G12D] inhibitor", "abstract_text": "KRAS[G12D] oncogenic mutation is present in ~35% of pancreatic, 13% of colorectal, and 4% of non-small cell lung cancers. The mutation also occurs in other cancer types, albeit less frequently. Here we would like to present compelling evidences that ZE98-0277 has potent and selective activity in KRAS[G12D] mutant cell lines and in vivo models.\nZE98-0277 drug candidate demonstrates strong in vitro activity (IC50 KRAS[G12D] 6.3 nM) and oral PK, bioavailability ~20-40% in mice and monkeys, broad therapeutic window (>100x in cellular models), good safety and tolerability, favorable ADME properties (solubility, stability, permeability, low hERG inhibition, minimal off-target effects), effective tumor suppression in multiple mouse xenograft models.\nThese preclinical results demonstrate that ZE98-0277 is a potent, selective, and orally bioavailable KRAS[G12D] inhibitor, strongly efficacious against KRAS[G12D] mutant tumors slated for further development.", "source_company": "Expert Systems, Inc\nExpert Systems, Inc.", "source_org_type": "公司", "row_number": 1243, "target_meta": "KRAS G12D", "MOA_meta": "抑制剂"}, {"drug_name": "DWP221", "company": "Daewoong Pharmaceutical", "org_type": "公司", "target": "AKT", "modality": "degrader", "importance_level": "高", "total_score": 79.5, "institution_score": 75, "track_score": 90, "milestone_score": 70, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "DWP221为口服生物利用的AKT degrader（PROTAC类），靶向PI3K-AKT通路关键节点AKT，提供持续降解克服传统抑制剂局限。Daewoong作为韩国TOP pharma（营收排名前3）机构实力较强，热门degrader赛道+口服+显著肿瘤抑制数据使其综合重要性高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8729", "id": "DVXM_5wBX1NQZOEH-LO6", "source_drug_name": "DWP221", "title": "Discovery of an orally bioavailable AKT degrader with sustained in vivo efficacy and translational potential", "abstract_text": "The PI3K-AKT signaling pathway is frequently dysregulated across solid tumors, including PIK3CA-mutant cancers. While several PI3K and AKT inhibitors have been approved for clinical use, therapeutic benefit remains limited by feedback reactivation and incomplete pathway suppression. We developed a novel, orally active small-molecule degrader designed to achieve sustained AKT removal and pathway inhibition.\nOur AKT degrader lead molecule DWP221/PIN002 induced rapid and sustained degradation of AKT in tumor cells and demonstrated a strong correlation between systemic exposure and pharmacologic response after oral dosing in tumor-bearing mice. In vivo, the degrader achieved dose-dependent tumor growth inhibition and showed preferential distribution to tumor tissue. Exploratory combination with fulvestrant further improved tumor growth control, supporting potential therapeutic complementarity in hormone receptor-positive tumors. DWP221/PIN002 was well tolerated throughout the study period, without notable body-weight loss or overt signs of systemic toxicity, and maintained a favorable exposure-response relationship consistent with its drug-like properties.\nThis study demonstrates that an orally bioavailable AKT degrader can achieve durable target suppression and in vivo efficacy through sustained exposure and efficient target engagement. These findings support that targeted protein degradation may overcome key limitations of conventional kinase inhibition and provide a differentiated approach toward next-generation targeted therapies for PI3K-AKT-driven cancers.", "source_company": "Daewoong Pharmaceutical", "source_org_type": "公司", "row_number": 1247, "target_meta": "Akt", "MOA_meta": "降解剂"}, {"drug_name": "BHB810", "company": "BigHat Biosciences, Inc.", "org_type": "公司", "target": "CDH17", "modality": "ADC", "importance_level": "高", "total_score": 79.5, "institution_score": 75, "track_score": 85, "milestone_score": 80, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "BHB810为靶向CDH17的VHH-Fc ADC，针对胃癌等GI肿瘤，CDH17在胃癌中广泛表达（50-60%+），BigHat为AI驱动的国外头部biotech平台，赛道ADC+新兴靶点热度高。预临床数据强劲，包括多PDX模型肿瘤清除、优异稳定性和安全性，计划2026年进入临床。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4287", "id": "NZ7M_5wBZznHJdnt_W3O", "source_drug_name": "BHB810", "title": "BHB810: A novel site-specific CDH17-directed VHH-Fc ADC for gastric cancer", "abstract_text": "Background: Gastric cancer remains a significant and growing cause of morbidity and mortality globally, with nearly 1 million newly diagnosed patients each year. Treatment paradigms are limited to checkpoint inhibitors, angiogenic blockade, and conventional chemotherapy, with few patients achieving durable responses. HER2 and CLDN18.2 directed therapies represent breakthroughs but substantial unmet need remains. CDH17 represents one of the most widely expressed tumor-associated antigens, offering the potential to treat 50-60% of patients with gastric cancer, including a substantial population of those without HER2 or CLDN18.2 expression.\nMethods: A single domain VHH anti-CDH17 antibody was engineered using BigHat’s Milliner platform for optimal internalization, humanized, and subsequently conjugated to MMAE via a site-specific and serum-stable, enzyme-cleavable linker using GlycoConnect SYNstatin E technology. The antibody drug conjugate (ADC) was subsequently interrogated in vitro and in vivo, including in cynomolgus macaques as part of a comprehensive preclinical therapeutic research program.\nResults: BHB810 is fully cross-reactive to human, cyno, and rodent orthologues and features robust and maximized internalization within 24 hours. The VHH-Fc fusion was conjugated to achieve a homogeneous DAR 4 with remarkable serum stability, providing a significantly enhanced therapeutic window compared to typical maleimide-vedotin conjugates. Compared to a benchmark clinical-stage CDH17-directed IgG ADC that rapidly loses payload via retro-Michael addition, BHB810 features no detectable deconjugation, payload transfer, or payload loss in human serum. The humanised VHH-Fc fusion backbone of BHB810 is 50% smaller than a typical IgG, resulting in superior tissue penetration. In PDX models, BHB810 leads to complete or near-complete tumor clearance in a panel of 13 different primary gastric cancers, including those with low and heterogeneous antigen densities. Preclinical modeling of pharmacokinetics and safety demonstrate a multi-day half-life, superior tolerability, and no evidence of on-target toxicities in non-malignant organ systems compared to benchmarks. In vivo imaging demonstrates robust target engagement and on-target ADC accumulation with reduced plasma exposure. BHB810 was evaluated in a 1 month GLP primate toxicity study exploring doses up to 5 mg/kg q2w (10 mg/kg of a conventional IgG ADC). No MTD was reached.\nConclusion: BHB810 is a novel, potentially best-in-class CDH17-directed ADC for the treatment of advanced gastric and other GI malignancies. The molecule was engineered on BigHat Biosciences’s AI/ML-powered antibody design platform to maximise ADC internalization and potency against cells that express CDH17. First-in-human studies are planned for 2026, prioritizing patients with gastric cancer.", "source_company": "BigHat Biosciences, Inc.", "source_org_type": "公司", "row_number": 1254, "target_meta": "CDH17", "MOA_meta": "抗体偶联药物"}, {"drug_name": "BCG026", "company": "Biocytogen", "org_type": "公司", "target": "FAP × GPC1", "modality": "bispecific ADC", "importance_level": "高", "total_score": 79.5, "institution_score": 75, "track_score": 90, "milestone_score": 65, "field_heat_score": 85, "bonus_score": 3, "brief_reason": "BCG026为靶向FAP（CAF基质）和GPC1（肿瘤细胞）的双特异性ADC，旨在同时打击胰腺癌等实体瘤的基质和肿瘤异质性，机制创新且针对难治肿瘤。机构为国内知名抗体技术平台公司（非头部top pharma/biotech但有全球合作和上市地位），热门bsADC赛道+胰腺癌未满足需求+PDX模型显效打分较高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4474", "id": "8lXM_5wBX1NQZOEH-LG6", "source_drug_name": "BCG026", "title": "BCG026: FAP × GPC1 bispecific ADC - A novel targeting approach for stromal and tumor cells in pancreatic cancer and other solid tumors", "abstract_text": "Background Pancreatic adenocarcinoma (PAAD) is a highly aggressive cancer that urgently needs new therapeutic strategies. Characterized by a dense fibrotic and desmoplastic stroma, PAAD leads to rapid disease progression, treatment resistance, and poor clinical outcomes. The primary components of this stroma are cancer-associated fibroblasts (CAFs), which accumulate within the tumor and increase the expression of collagen and fibronectin, thereby remodeling the extracellular matrix. CAFs also facilitate the desmoplastic response, contributing to early invasion, high recurrence rates, and resistance to treatment in PAAD. As a result, CAFs represent a promising therapeutic target not only in PAAD but also in other solid tumors. Fibroblast activation protein (FAP) is selectively expressed by CAFs in the majority of human epithelial cancers. Glypican 1 (GPC-1) is aberrantly expressed and plays a significant role in various cancers. It is notably increased in PAAD and has also been found at elevated levels in colorectal, prostate, and breast cancers.\nWe have confirmed that the PAAD tissue microarray (TMA) showed high expression levels of both FAP and GPC1. In response, we developed BCG026, a novel bispecific ADC that targets both stromal and tumor cells. This approach aims to deplete the tumor stroma, thereby improving efficacy against the stroma barrier and tumor heterogeneity, as well as overcoming resistance associated with traditional single-target therapies. A fully human bispecific antibody against FAP and GPC1 was generated using Biocytogen's RenLite® transgenic mice. The bsAb backbone demonstrated high affinity for both FAP and GPC1, effectively binding to a diverse panel of tumor cells.\nResults Furthermore, it exhibited robust binding activity in both stromal and tumor cells, regardless of their varying expression levels of FAP and GPC1. Notably, the bsAb also showed efficient internalization in both stromal and tumor cells, indicating its capacity to deliver therapeutic payloads effectively to stroma and tumor cells. We then conjugated the bsAb with TOP1i linker-payload (BLD1102) to create BCG026. This novel bsADC exhibited a CAF-dependent bystander killing effect in vitro, suggesting its ability to induce cytotoxicity in FAP-positive stroma and tumor cells that may not express the target antigens, but are present in proximity to CAFs. Furthermore, BCG026 demonstrated potent efficacy in pancreatic and lung cancer PDX models, as well as a superior synergistic effect to that of the parent ADCs in certain models.\nConclusion These findings underscore its significant potential as a powerful therapeutic agent for targeting PAAD and other tumors. Further preclinical studies are currently underway.", "source_company": "Biocytogen", "source_org_type": "公司", "row_number": 1269, "target_meta": "FAP,GPC1", "MOA_meta": "抗体偶联药物"}, {"drug_name": "LUA004", "company": "Shanghai Qilu Pharmaceutical Research and Development Center LTD", "org_type": "公司", "target": "5T4", "modality": "ADC", "importance_level": "高", "total_score": 79.5, "institution_score": 85, "track_score": 75, "milestone_score": 75, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "LUA004为靶向5T4的ADC，采用新型微管抑制剂payload和位点特异性偶联，展示优于vedotin ADC的疗效窗和耐受性。齐鲁制药作为国内TOP pharma（近年多次位列前3-5），ADC赛道热门但5T4靶点非最热，preclinical数据强劲包括cyno猴高耐受，支持较高综合评分。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5452", "id": "XJ7M_5wBZznHJdnt_W7P", "source_drug_name": "LUA004", "title": "Preclinical characterization of LUA004, a novel 5T4-targeting ADC with improved therapeutic window", "abstract_text": "Background: Trophoblast glycoprotein (5T4), an oncofetal protein, is a member of the leucine-rich repeat family of proteins that is associated with intercellular connectivity, cell morphology and movement, and altering cell adhesion in embryonic development and cell differentiation. 5T4 is upregulated in several cancers, including esophageal, head-and-neck, and lung cancers, especially the squamous subtype, with low or absent expression in adult normal tissues. The high expression of 5T4 was notably correlated with poor survival in different cancer types, which makes it an attractive ADC target. The therapeutic potential of 5T4 as ADC modality was recently unraveled by several ADCs with preliminary clinical efficacy reported. In this study, we present the development of a novel 5T4-targeting ADC with Qilu’s proprietary microtubule inhibitor as payload, LUA004, which exhibited excellent efficacy and expanded therapeutic window than vedotin ADC.\nMethod: LUA004 utilizes a novel microtubule inhibitor payload QLS8152 with a proprietary cleavable linker to achieve a homogeneous product with a drug-to-antibody ratio (DAR) of 8 through site-specific conjugation. The payload QLS8152 showed sub-nanomolar activity across a wide range of cancer cell lines in vitro and rapid systematic clearance in rodent models. Our next generation microtubule inhibitor platform QLS8153 demonstrated significantly improved therapeutic window than vedotin technology.\nResult: LUA004 showed sub-nanomolar binding affinity and dose-dependent internalization in multiple tumor cell lines with different 5T4 expression levels. LUA004 showed strong (nM range IC50) and comparable in vitro cytotoxicity to vedotin-ADC against a variety of 5T4-positive cancer cell lines. Meanwhile, LUA004 showed robust and dose-dependent tumor inhibition in different cell-derived xenograft (CDX) as well as patient-derived xenograft (PDX) models with various 5T4 expression, with comparable tumor inhibition as vedotin-ADC. Moreover, compared to vedotin-ADC, LUA004 exhibits more favorable plasma stability, preclinical pharmacokinetic, and toxicity profiles. LUA004 was well tolerated in cyno monkeys, with HNSTD up to 20 mpk Q3W x 4 in non-GLP toxicity study, indicating a tremendous increase in the therapeutic index compared to vedotin-ADC.\nConclusion: LUA004 represents a novel 5T4-targeting ADC with favorable anti-tumor activity and superior tolerability, which can address the high unmet needs in patients with cancers expressing variable levels of 5T4. The promising preclinical profiles of LUA004 warrant its further development into clinical trials.", "source_company": "Shanghai Qilu Pharmaceutical Research and Development Center LTD", "source_org_type": "公司", "row_number": 1278, "target_meta": "TPBG", "MOA_meta": "抗体偶联药物"}, {"drug_name": "GQ1035", "company": "GeneQuantum Healthcare (Suzhou) Co., Ltd.", "org_type": "公司", "target": "未披露", "modality": "ADC", "importance_level": "高", "total_score": 79.5, "institution_score": 75, "track_score": 90, "milestone_score": 70, "field_heat_score": 85, "bonus_score": 3, "brief_reason": "GQ1035为针对新型靶点（Target A）的First-in-class ADC，在胃癌和卵巢癌领域通过高通量筛选发现，靶点独立于CLDN18.2和FRα，具有潜在突破性。机构为国内专注ADC的创新biotech，已有多个临床阶段ADC并与头部企业合作，赛道热门且preclinical数据较强，包括PDO/PDX模型肿瘤消退及NHP安全性研究。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4471", "id": "LlXM_5wBX1NQZOEH-LK6", "source_drug_name": "GQ1035", "title": "GQ1035: First-in-class ADC against novel targets for gastric cancer and ovarian cancer discovered via high-throughput screening​", "abstract_text": "Background:Antibody-drug conjugates (ADCs) constitute a breakthrough in gastric cancer (GC) and ovarian cancer (OV) therapy; however about over 50% of patients remain ineligible for existing options, underscoring the urgent need for next-generation ADCs against novel targets. Among these, Target A has emerged as a promising candidate due to its high expression in GC and OV, with no significant correlation to CLDN18.2 or FRα—supporting its potential for ADC development. The iScreener™ platform's high-throughput conjugation capability, rooted in iLDC™/iGDC™ technologies, enables a screening-based strategy for the rapid identification of lead ADCs against Target A.\nMethod/Results:To develop ADCs against Target A, we constructed a diverse library of ~150 candidates on the iScreener™ platform by combining 11 antibodies with varied linker-payloads. The ADC library was screened using gastric cancer patient-derived organoid (PDO) models. In this screen, TopoIi-ADC and Exatecan-ADC demonstrated superior anti-tumor activity compared to other payload-based ADCs (e.g., DXd, MMAE, Eribulin). During in vivo screening, TopoIi-ADCs and Eribulin-ADCs emerged as the top candidates by demonstrating potent anti-tumor efficacy in a model resistant to a Topo1 inhibitor-based ADC. Through further refinement in PDX models, GQ1035 was selected based on its ability to induce significant tumor regression across models with varying target expression levels, while maintaining a good safety profile with no significant body weight loss. Safety study for lead candidate is currently ongoing in non-human primates (NHPs).\nConclusion:GQ1035 shows a promising efficacy profile against gastric and ovarian cancers in preclinical PDO and PDX models. This positions GQ1035 as a potential breakthrough therapy in an area of high unmet medical need. It stands as a pioneering example of the strategic shift in biomedicine from “by design” to “by screening”.", "source_company": "GeneQuantum Healthcare (Suzhou) Co., Ltd.", "source_org_type": "公司", "row_number": 1286, "target_meta": "not available", "MOA_meta": "抗体偶联药物"}, {"drug_name": "AR170", "company": "Y-Biologics", "org_type": "公司", "target": "PD-1, VEGF, IL-2 receptor", "modality": "immunocytokine", "importance_level": "高", "total_score": 79.3, "institution_score": 65, "track_score": 92, "milestone_score": 75, "field_heat_score": 85, "bonus_score": 8, "brief_reason": "AR170为新型PD-1×VEGF×IL-2v三特异性immunocytokine，通过VEGF诱导二聚化实现cis-acting IL-2v信号并Fc沉默，显著优于PD-1单抗及PD-1×VEGF双抗，在人源化模型中展现优异抗瘤效果及安全性。Y-Biologics作为韩国头部抗体biotech，赛道为热门三特异性免疫治疗+热门靶点组合，preclinical数据强劲且具新机制亮点。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4508", "id": "nVXM_5wBX1NQZOEH-LG6", "source_drug_name": "AR170", "title": "AR170, a novel PD-1xVEGFxIL-2v tri-specific immunocytokine to redefine next generation cancer immunotherapy", "abstract_text": "Background\nBispecific antibodies that simultaneously target PD-1 and VEGF have shown promise in extending the efficacy of PD-1 inhibition alone, yet despite improved treatment response and prolonged progression-free survival, overall survival advantage over anti-PD-1 monotherapy is so far limited. Interleukin-2 (IL-2) combination can markedly potentiate the efficacy of PD-1xVEGF bispecific antibodies, but challenges remain due to systemic toxicity. To overcome this limitation, AR170 was designed as a novel tri-specific immunocytokine that simultaneously engages PD-1, VEGF, and the IL-2 receptor by incorporating an optimized cis-acting IL-2 variant (IL-2v) and complete Fc-silencing.\nMethods\nVEGF-induced AR170 dimerization was assessed by SE-HPLC. Enhanced PD-1 binding after dimerization was confirmed using bio-layer interferometry (BLI) and flow cytometry. Blockade of PD-1/PD-L1 and VEGF/VEGFR interactions was validated using a luciferase reporter assay. Functional assays were conducted to measure T cell activation, proliferation, cytotoxicity, and cytokine secretion by flow cytometry or ELISA. Fc-silencing was confirmed by ADCC, ADCP, and CDC assays. Antitumor efficacy was evaluated in both hPBMC-engrafted and hPD-1/hPD-L1/hVEGF triple knocked-in mouse models. Safety and pharmacokinetic studies were carried out in hIL-2R knock-in mice and cynomolgus monkeys.\nResults\nAR170 undergoes VEGF-induced dimerization that synergizes blockade activity of both PD-1 and VEGF. AR170 delivers PD-1-dependent cis-acting IL-2v signaling. In addition, Fc-silencing technology effectively minimizes Fc-mediated effector function. AR170 under VEGF-enriched exhaustion conditions induced robust proliferation and activation of CD8+ T cells compared to either PD-1 inhibitor or PD-1xVEGF bispecific antibody in vitro. AR170 elicited rapid and durable antitumor responses superior to either PD-1 inhibitor or PD-1xVEGF bispecific antibody in VEGF-expressing tumor-bearing (≥300 mm³) humanized mouse models, while depletion of CD8+ T cells eliminated antitumor efficacy. Immune cell profiling showed elevated proportion of TCF1⁺PD-1⁺CD8⁺ T cells following AR170 treatment. AR170 demonstrated favorable safety and pharmacokinetic profiles in both mice and cynomolgus monkeys.\nConclusions\nAR170 is a next-generation cancer immunotherapy that uses a novel IL-2v fusion approach to surpass the efficacy limitations of PD-1xVEGF bispecific antibodies.", "source_company": "Y-Biologics", "source_org_type": "公司", "row_number": 188, "target_meta": "PD1", "MOA_meta": "其他"}, {"drug_name": "HY809382", "company": "Yangtze River Pharmaceutical (Group) Co., Ltd.", "org_type": "公司", "target": "EED (PRC2 complex)", "modality": "PROTAC", "importance_level": "高", "total_score": 79.2, "institution_score": 65, "track_score": 92, "milestone_score": 82, "field_heat_score": 88, "bonus_score": 6, "brief_reason": "HY809382为口服生物利用度高的PRC2 PROTAC，通过特异降解EED及EZH2展现优于现有EZH2抑制剂的活性，并在多种肿瘤模型中显示显著疗效。长江药业作为国内头部药企，PROTAC赛道+EED靶点+强前临床数据及良好安全性共同支撑较高综合重要性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6450", "id": "pZ7M_5wBZznHJdnt_W3O", "source_drug_name": "HY809382", "title": "Preclinical characterization of HY809382, a highly potent and orally bioavailable PRC2 PROTAC, for the treatment of lymphoma and solid tumors", "abstract_text": "The Polycomb repressive complex 2 (PRC2) is a key epigenetic regulator that mediates gene silencing through the catalysis of histone H3 lysine 27 trimethylation (H3K27me3). This activity facilitates repression of tumor suppressor genes as well as immune-related transcripts. The core subunits of PRC2 comprise EED, SUZ12, and the catalytic component EZH1 or EZH2. Aberrations of PRC2 components, including mutation and overexpression, have been identified across a range of cancers, highlighting PRC2 as a promising therapeutic target. Although targeting EZH2 has been the primary approach in PRC2 inhibitor development, leading to the FDA approval of Tazemetostat as the first-in-class agent, no PRC2 degraders have yet progressed to clinical trials. The PRC2 degraders provide several potential advantages, such as ​overcoming​ acquired resistance to approved EZH2 inhibitors, ​disrupting​ the stability of the PRC2 complex, and ​enhancing​ efficacy against lymphoma and solid tumors. Herein we disclose HY809382, an orally bioavailable PRC2-targeting PROTAC molecule, as a candidate therapeutic for lymphoma and solid tumors. HY809382 demonstrated degradation of the target protein EED at nanomolar (nM) concentrations, without altering protein levels of known CRBN neo-substrates such as IKZF1/3, GSPT1 and CK1α. Proteomic analysis confirmed that HY809382 selectively degraded the target protein EED and its co-complex partner EZH2, demonstrating excellent degradation specificity. The antiproliferative activity of HY809382 surpassed that of approved or clinically investigated small molecule inhibitors targeting PRC2 components. HY809382 exhibited favourable oral pharmacokinetics in preclinical species, with bioavailability (F)≥ 40%. Once-daily oral administration of HY809382 demonstrated significant, dose-dependent tumor growth inhibition in Karpas-422 (DLBCL), G401 (rhabdoid tumor) and 22Rv-1 (prostate cancer) cell-derived xenograft models, outperforming approved or clinically investigated PRC2-related inhibitors. IHC analysis confirmed HY809382-mediated downregulation of key on-target pharmacodynamic markers (e.g., H3K27me3, EED and EZH2) in tumor tissues. A 44-target safety screen indicated a clean off-target profile, and the compound showed low risks of cardiotoxicity and genotoxicity, as supported by hERG inhibition and the mini-Ames tests, respectively. Preliminary non-GLP repeated-dose toxicity studies in mice and cynomolgus monkeys indicated that HY809382 was well tolerated, with estimated therapeutic windows of >95 and >25, respectively. These findings support the potential of HY809382 as a best-in-class PRC2 degrader and warrant its further evaluation in IND-enabling studies.", "source_company": "Yangtze River Pharmaceutical (Group) Co., Ltd.", "source_org_type": "公司", "row_number": 272, "target_meta": "EED", "MOA_meta": "PROTAC"}, {"drug_name": "Compound D", "company": "Deciphera Pharmaceuticals, LLC", "org_type": "公司", "target": "microtubule 和 RAF", "modality": "inhibitor", "importance_level": "高", "total_score": 79, "institution_score": 75, "track_score": 85, "milestone_score": 75, "field_heat_score": 80, "bonus_score": 8, "brief_reason": "Compound D 为首创的双微管和 RAF 靶向抑制剂，同时结合 colchicine 位点和 RAF 激酶，可克服 MDR1 耐药并在 BRAF/KRAS 突变模型中单药显示肿瘤消退或抑制。Deciphera 作为头部国外 biotech（现 Ono 子公司）在 kinase 领域有强积累，该 dual mechanism 新颖且针对 RAS/MAPK 驱动癌症（30%肿瘤），preclinical 数据扎实具 CNS 渗透性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8795", "id": "IVXM_5wBX1NQZOEH-LK6", "source_drug_name": "Compound D", "title": "Discovery of a first-in-class dual microtubule- and RAF—targeting inhibitor", "abstract_text": "Background: Microtubule-targeting agents (MTAs) are effective first-line cancer therapies, but novel agents are needed to overcome resistance mechanisms, minimize toxicities, improve delivery, and enhance outcomes with new combination strategies. Several kinase inhibitors have been shown to be MTAs, with some dual inhibitors demonstrating lower toxicities. However, no reported compounds have demonstrated dual RAF kinase-and microtubule-targeting activities. Given that mutations in the RAS/MAPK pathway drive 30% of all cancers, we sought to develop dual microtubule- and RAF—targeting inhibitors.\nMethods: Tubulin polymerization inhibition and competition with a BODIPY-colchicine probe were measured using recombinant tubulin. RAF kinase inhibition and off-rate analysis were measured using recombinant enzymes. Structure-based drug design was enabled by X-ray crystallography. Cellular microtubule modulation was determined by a microtubule sedimentation assay, and cellular inhibition of pERK and pRSK was measured by AlphaLISA or ELISA. Cellular proliferation was monitored via resazurin. Spindle formation, cell cycle, and apoptosis were measured by immunofluorescence, flow cytometry, and Western blot. Pharmacokinetics (PK) in plasma, brain, and cerebrospinal fluid compartments were measured following oral dosing in rats. In vivo efficacy was assessed in RAF- and RAS-mutant mouse xenograft models.\nResults: Compound D is an MTA that binds at the colchicine binding site and is also potent and selective for inhibition of RAF kinases. The dual-targeting mechanism was further validated via co-crystallization with the tubulin-stathmin-TTL complex and separately with BRAF. Inhibition of MAPK pathway signaling and cellular proliferation was observed in a wide range of BRAF- and KRAS-altered cell lines. In addition, compound D overcomes the tubulin-inhibitor resistant mechanism of MDR1 overexpression. Mechanistically, compound D disrupts normal spindle formation and induces G2/M arrest and apoptosis. Compound D has favorable ADME and PK properties, is orally available, and CNS-penetrant. Oral treatment as a single agent resulted in tumor regression or tumor growth inhibition in BRAF- and KRAS-mutant mouse xenograft models.\nConclusions: Compound D is the first reported microtubule destabilizing agent with dual RAF activity, leading to tumor regression or growth inhibition as a single agent in preclinical models. Our data provide proof of concept for designing orally available CNS-penetrant inhibitors targeting both microtubules and RAF kinases.", "source_company": "Deciphera Pharmaceuticals, LLC", "source_org_type": "公司", "row_number": 157, "target_meta": "microtubule,CRAF", "MOA_meta": "抑制剂"}, {"drug_name": "proprietary LNP platform", "company": "Cytiva", "org_type": "公司", "target": "未披露", "modality": "mRNA", "importance_level": "高", "total_score": 79, "institution_score": 75, "track_score": 90, "milestone_score": 65, "field_heat_score": 85, "bonus_score": 3, "brief_reason": "该平台为专有离子化脂质LNP，用于递送多表位mRNA癌症疫苗，在黑色素瘤模型中显著抑制肿瘤生长并延长生存，体现mRNA+LNP热门赛道潜力；Cytiva作为Danaher旗下全球生命科学工具和服务领导者，非典型drug开发公司但在mRNA递送领域有技术优势，preclinical数据清晰但仍早期阶段。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10420", "id": "ulXM_5wBX1NQZOEH-LO6", "source_drug_name": "proprietary LNP platform", "title": "Towards personalized cancer vaccines: LNP-mediated delivery of multi-epitope mRNA extends survival in aggressive melanoma cancer model", "abstract_text": "Personalized cancer vaccines (PCVs) open new doors for immunotherapy by harnessing the immune system to target tumor specific neoantigens ― mutated proteins ― unique to an individual’s cancer. Lipid nanoparticle (LNP)-based mRNA vaccines, shown to be effective against COVID-19, serve as a suitable platform for delivering multi-epitope neoantigen mRNA payloads. LNP drug product for PCV applications however, may require optimization of the multi-antigenic mRNA cargo, target tissue uptake, and endosomal release, along with frequent therapeutic dosing. We identified 10 melanoma-specific antigens and synthesized multiple multi-antigen mRNA constructs encoding various antigen combinations, with and without marker epitopes such as ovalbumin (OVA), eGFP, and firefly luciferase (Fluc). We developed proprietary ionizable lipids and encapsulated the various multi-epitope mRNA constructs in LNPs and evaluated their performance in well-established in vitro cell based assays and a B16F10 syngeneic mouse melanoma model. The in vitro cell-based assays confirmed effective LNP-mediated delivery, mRNA translation, and antigen presentation via major histocompatibility complex (MHC) molecules. In vivo imaging demonstrated payload expression 6 hours post-injection. Selected multi-epitope mRNA-LNP formulations were administered intramuscularly in B16F10 tumor-bearing mice. Multi-epitope comprising LNPs significantly reduced mean tumor growth rate and extended survival in vaccinated mice compared to controls. Additionally, repeated dosing regimens showed favorable safety profiles. These results demonstrate that our proprietary LNP platform efficiently delivers multi-epitope mRNA LNPs, eliciting potent anti-tumor immune responses in a relevant melanoma model and demonstrating safety of repeated LNP administrations for shared or individualized cancer vaccine applications. This positions our LNP as a promising candidate for further developing PCVs and accelerating new personalized medicine to clinic.", "source_company": "Cytiva", "source_org_type": "公司", "row_number": 778, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "INC-DGKi", "company": "Incyte Corporation", "org_type": "公司", "target": "DGKA/DGKZ", "modality": "inhibitor", "importance_level": "高", "total_score": 79, "institution_score": 85, "track_score": 85, "milestone_score": 65, "field_heat_score": 80, "bonus_score": 0, "brief_reason": "INC-DGKi为Incyte的双DGKA/DGKZ抑制剂（小分子抑制剂），通过增强T细胞激活并改善肿瘤微环境，与PD-1抑制剂联合显示互补抗肿瘤效应。机构为国外头部biotech公司、赛道为新兴免疫热点靶点+热门组合策略、处于强preclinical功能验证阶段，综合潜力较高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5173", "id": "uZ7M_5wBZznHJdnt_W3O", "source_drug_name": "INC-DGKi", "title": "Differential tumor and immune responses to anti PD-1 and DGK inhibition in patient-derived tumor spheroids reveal additive killing effect", "abstract_text": "PD-1 checkpoint blockade has transformed cancer therapy, yet durable responses remain confined to a subset of patients. Diacylglycerol kinase (DGK) inhibition has been proposed as a complementary strategy to enhance T-cell activation and reprogram the tumor microenvironment. We tested a novel dual DGKA and DGKZ inhibitor using a patient-derived organotypic tumor spheroid (PDOTS) platform that preserves tumor, stromal, and immune architecture, enabling functional assessment of therapeutic response in a physiologic ex vivo context. PDOTS from 22 patient tumors were treated with retifanlimab-dlwr (PD-1 inhibitor), DGK inhibitor (INC-DGKi) at two doses, or the combination. Tumor response was defined as a log₂ fold-change < -0.5 in epithelial tumor load (EpCAM⁺) or a composite epithelial marker set to account for squamous cell carcinomas. Immune activation was profiled by multiplexed gene expression emphasizing CD8⁺ effector activity, interferon-stimulated genes, cytokine induction, and antigen presentation. Baseline PD-L1 and MHC-I were measured by flow cytometry. Responsive (R) and non-responsive (NR) tumors were defined by tumor killing and/or immune activation and compared by differential expression and pathway analyses. Retifanlimab induced tumor regression in 6 of 22 (~27%) tumors and triggered immunologic activity in 10 of 22 (~46%), including increased CD8⁺ and NK activity and interferon gene induction. DGKi elicited tumor regression in 5 of 22 (~23%) and stimulated immune-related transcriptional programs in 11 of 22 (~50%), representing largely distinct responders, with pro-inflammatory and leukocyte recruitment pathways enriched. Combination treatment induced tumor regression in 9 of 22 (~41%) and elicited immune activation in 6 of 22 (~27%), exceeding monotherapy cytotoxicity. Baseline PD-L1 and MHC-I variably correlated with response, indicating contextual, not universal, biomarkers. Retifanlimab and DGKi each elicited antitumor and immune responses in distinct tumor subsets, with comparable single-agent activity. Combination therapy improved tumor killing but not immune engagement, suggesting complementarity of the two agents and merits additional studies to clarify the observed discordance between tumor regression and immune signals in the combination setting. These data support biomarker-guided approaches and highlight PDOTS as a translational platform for defining rational immunotherapy combinations.", "source_company": "Incyte Corporation", "source_org_type": "公司", "row_number": 1257, "target_meta": "DGKα,DGKZ", "MOA_meta": "抑制剂"}, {"drug_name": "RT023", "company": "Shanghai Ruotuo Biosciences Co., Ltd.", "org_type": "公司", "target": "CEACAM5/EGFR", "modality": "ADC", "importance_level": "高", "total_score": 78.8, "institution_score": 65, "track_score": 92, "milestone_score": 82, "field_heat_score": 85, "bonus_score": 6, "brief_reason": "RT023为首创CEACAM5/EGFR双靶点ADC，针对CRC尤其是KRAS突变或EGFR抗体耐药患者，bispecific ADC+exatecan设计提升了异质表达肿瘤杀伤力。国内biotech公司，热门ADC赛道+双靶点+强效CDX数据（包括CR和优于对照）+良好猴毒性和PK，支持较高综合评分。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5390", "id": "-VXM_5wBX1NQZOEH-LG6", "source_drug_name": "RT023", "title": "RT023, a first-in-class CEACAM5/EGFR targeted bispecific antibody drug conjugate (ADC) in colorectal cancer (CRC)", "abstract_text": "Background: CEACAM5 and EGFR are highly expressed in several cancers, including colorectal, gastric, and lung, with greater specificity than in normal tissues. EGFR antibodies like cetuximab are standard first-line therapy for colorectal cancer (CRC) patients with wild-type KRAS, but are less effective in those with KRAS mutations, creating an unmet clinical need. ADCs targeting CEACAM5 or EGFR, such as M9140 and MRG003, are under clinical development for CRC; however, single-target ADCs have shown limited efficacy, likely due to variable antigen expression among patients. To address this, we developed RT023, a CEACAM5/EGFR bispecific ADC designed to treat patients positive for either marker, including those with KRAS mutations and those who relapse after EGFR antibody treatment.\nMethods: RT023 is an ADC composed of an anti-CEACAM5/anti-EGFR bispecific antibody and a DNA topoisomerase I inhibitor, exatecan, linked through a cleavable linker, with a homogeneous drug-to-antibody ratio (DAR) of 6. In vitro potency was measured through cytotoxicity assay. Its anti-tumor activities were evaluated in cell line-derived xenograft (CDX) models. Toxicity and pharmacokinetics of RT023 were assessed in cynomolgus monkey.\nResults: RT023 exhibited high affinity binding to CEACAM5 and EGFR. It had higher internalization rate than its respective parent monospecific antibodies, resulting in efficiently killing to tumor cells with a wide spectrum of CEACAM5 and EGFR expression levels. RT023 demonstrated superior tumor growth inhibition than M9140 and Cetuximab ADC in several CRC CDX models. In the EGFR-dominant HCT116 model, RT023 exhibited impressive tumor growth inhibition with a TGI of 88.5% after single dose of 0.77 mg/kg, whereas the Cetuximab ADC at the same molar dose achieved only a 58% TGI, and M9140 did not inhibit tumor growth. In the CEACAM5-dominant GP2D model, a single dose treatment of RT023 at 2.3 mg/kg resulted in 80% (4/5) complete tumor regression (CR), whereas M9140 treatment group only achieved 20% (1/5) CR. In the CEACAM5 /EGFR double-driven SW1116 model, RT023 induced tumor repression with a higher TGI than Cetuximab ADC (117% vs 105%) after two doses of 2.3 mg/kg, Q3W, and showed more durable anti-tumor effect than M9140 (64 days vs 47 days). RT023 was well tolerated in cynomolgus monkeys up to 30 mg/kg, with only minimal skin and hematological adverse effect. It also had a favorable PK profile with a half-life of approximately 120 hours. RT023 remained stable in circulation with less than 0.02% free drug release.\nConclusion: RT023, with its unique bispecific design and differentiated features in affinity, linker-payload, has shown promising potential as a first-in-class ADC candidate for CRC treatment. Preclinical discovery studies have revealed favorable efficacy and toxicity profiles, supporting advancing RT023 into first-in-human studies.", "source_company": "Shanghai Ruotuo Biosciences Co., Ltd.", "source_org_type": "公司", "row_number": 124, "target_meta": "CEACAM5,EGFR", "MOA_meta": "抗体偶联药物"}, {"drug_name": "covalent fragment hits", "company": "Frontier Medicines", "org_type": "公司", "target": "未披露", "modality": "other", "importance_level": "高", "total_score": 78.5, "institution_score": 75, "track_score": 90, "milestone_score": 65, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "药物为基于AI和chemoproteomics的covalent fragment hits，针对多种难成药癌靶如KEAP1、MYC等，体现covalent药物发现平台先进性。机构为专注covalent和undruggable靶点的临床阶段biotech，赛道热门（covalent AI驱动药物发现），有preclinical hits和平台技术亮点但未到具体候选物临床阶段。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3181", "id": "C1XM_5wBX1NQZOEH-LS6", "source_drug_name": "covalent fragment hits", "title": "Finding Goldilocks: How AI-powered covalent drug discovery removes the “un” from “undruggable”", "abstract_text": "Covalent drugs offer a path to drugging hard targets to provide urgently needed novel cancer medications. Starting from small covalent fragments is efficient in principle but difficult in practice due to challenges distinguishing generic from specific reactivity and the influence of the reactive warhead on all other chemical properties. The Frontier™ Platform and covalent AI as a key pillar overcomes these challenges. Focused super large-scale experimental data generation relevant to covalent drug discovery has enabled the development of several powerful covalent AI algorithms. Their application falls into two different fields, firstly the better understanding of the proteome and proteins and potential covalent binding sites and secondly in advancing covalent chemistry. We detail strategic data generation through chemoproteomics experiments, quantum mechanics, experimental chemical property determination, and the leveraging of these data to inform covalent drug discovery for hard-to-drug targets. This includes the AI-driven characterization of covalent binding sites across nearly the complete human proteome. Covalent fragment hits have been identified for multiple difficult cancer targets including KEAP1, ADAR, DHX9, PTPN11, MYC, and many others (>75% of important cancer driver genes). Furthermore, we will highlight several novel AI covalent chemistry applications. We will present an algorithmically designed covalent fragment library for screening, covalent chemical property prediction algorithms, and details of our highly specialized AI-driven covalent drug design engine that autonomously ingests all relevant data for a given project and suggests optimized compounds to be synthesized. We show the impact of this approach for a historically undruggable transcription factor and cancer driver as an example. Undruggable targets across a variety of cancer target classes have become druggable leaning on advanced covalent drug discovery methods.", "source_company": "Frontier Medicines", "source_org_type": "公司", "row_number": 68, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "ZMS-4084", "company": "Simcere Zaiming Pharmaceutical Co, Ltd.", "org_type": "公司", "target": "WRN", "modality": "inhibitor", "importance_level": "高", "total_score": 78.5, "institution_score": 75, "track_score": 85, "milestone_score": 75, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "ZMS-4084为新型高效选择性WRN抑制剂，靶向MSI-H肿瘤的合成致死机制，在多种MSI-H模型中展现显著肿瘤消退和持续完全缓解。先声再明作为国内领先创新药企子公司，WRN作为MSI-H癌种热门新兴靶点，preclinical数据强劲且口服潜力大。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6413", "id": "Dp7M_5wBZznHJdnt_W7O", "source_drug_name": "ZMS-4084", "title": "ZMS-4084, a potent and selective WRN inhibitor induces significant tumor regression and sustained complete responses in MSI-H tumor models", "abstract_text": "Microsatellite instability-high status (MSI-H) is typically prevalent in endometrial, gastrointestinal, ovarian and colorectal cancers. The RecQ helicase WRN has been identified as a synthetic lethal target in MSI-H cancers and represents a promising therapeutic candidate in this context. The two clinical-stage WRN inhibitors, HRO761 and RO7589831, have demonstrated the clinical efficacy in phase I trials. Here we report the discovery of a novel and potent WRN inhibitor, ZMS-4084. Surface plasmon resonance analysis revealed that ZMS-4084 binds specifically to the WRN helicase domain with high affinity (KD=1.08E-08 M). ZMS-4084 selectively inhibited WRN ATPase activity with an IC50 of 0.05 µM, and exhibited over 2,000-fold selectivity over other RecQ family helicases. Intracellular mechanistic study demonstrated that ZMS-4084 induces apoptosis and inhibits proliferation of HCT116 (MSI-H) cells with an EC50 of 0.024 µM, accompanied by WRN degradation and accumulation of DNA damage signified by p21 expression and other markers. In a panel of 124 tumor cell lines, ZMD-4084 selectively inhibited the viability of MSI-H cell lines without significant effects on microsatellite stable (MSS) cell lines, indicating high selectivity and a potentially favorable safety profile. Notably, ZMD-4084 effectively suppressed the growth of MSI-H patient-derived organoids, including those previously exposed to standard-of- care therapies such as chemotherapy, anti-EGFR agents, and/or immunotherapy. In vitro ADME and in vivo pharmacokinetics studies demonstrated favorable physicochemical properties and dose-proportional oral bioavailability across preclinical species, supporting its potential for oral administration in humans. Daily administration of ZMS-4084 resulted dose-dependent antitumor efficacy in xenograft models derived from MSI-H human tumors. In the Ishikawa xenograft model, daily dosing at 2.5 mg/kg induced 100% tumor regression, and complete responses (CRs) were achieved in five out of six aminals at 15 mg/kg. Even in the less sensitive RKO xenograft model, 100% tumor regression and several CRs were observed at a dose of 20 mg/kg. No treatment-related abnormalities were observed across all dose regimens in non-GLP preclinical safety studies. In conclusion, we have developed a novel WRN inhibitor, ZMS-4084, which demonstrates robust antitumor activity in both xenograft models and patient-derived organoids representing diverse MSI-H tumor types. Given the synthetic lethality between WRN inhibition and MSI-H status, along with its broad antitumor activity across multiple tumor lineages, ZMS-4084 holds strong potential as a tissue-agnostic therapeutic agent for patients with MSI-H tumors.", "source_company": "Simcere Zaiming Pharmaceutical Co, Ltd.", "source_org_type": "公司", "row_number": 114, "target_meta": "WRN", "MOA_meta": "抑制剂"}, {"drug_name": "ARK102", "company": "ARKGENBioScions", "org_type": "公司", "target": "TROP2, HER2, CD3", "modality": "TCE", "importance_level": "高", "total_score": 78.5, "institution_score": 65, "track_score": 90, "milestone_score": 75, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "ARK102为新型trispecific TCE，同时靶向TROP2、HER2和CD3，针对实体瘤双靶点共表达增强亲和力并克服异质性；机构为韩国新兴biotech，赛道热门（trispecific TCE+热门靶点TROP2/HER2），preclinical显示优于benchmark ADC的抗瘤活性及良好安全性，支持较高综合评分。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4543", "id": "cZ7M_5wBZznHJdnt_W7P", "source_drug_name": "ARK102", "title": "ARK102, a novel tri-specific T cell engager targeting TROP2, HER2, and CD3 for treatment of solid tumors", "abstract_text": "ARK102 is a novel trispecific T‑cell engager in a fragment format lacking an Fc domain, engineered using proprietary platform technology to simultaneously target HER2 and TROP2 while recruiting CD3 T cells for potent redirected cytotoxicity. HER2 and TROP2 are clinically validated tumor‑associated antigens that have demonstrated favorable outcomes across multiple therapeutic modalities. However, limited target expression in some tumors can restrict therapeutic efficacy. As HER2 and TROP2 are broadly co‑expressed across diverse malignancies, dual targeting of these antigens offers an innovative strategy to enhance tumor binding through increased avidity and to overcome challenges such as tumor heterogeneity, antigen loss, and resistance to existing therapies.Comprehensive in vitro analyses showed that ARK102 effectively binds both target antigens, activates T cells, and mediates T‑cell-dependent cytotoxicity in dual and single target‑expressing cancer cell lines at sub‑nanomolar concentrations. In vivo, ARK102 demonstrated robust, dose‑dependent antitumor activity in human PBMC‑reconstituted immunodeficient mice bearing HER2‑ and/or TROP2‑expressing tumor xenografts, without dose‑limiting toxicity at efficacious doses, and showed antitumor efficacy comparable to or greater than that of benchmark TROP2‑ADC and HER2‑ADC therapies.Together, these results highlight ARK102 as a potent and selective dual‑targeting T‑cell engager with the potential to expand treatment options for patients with solid tumors co‑expressing HER2 and TROP2. The compelling preclinical efficacy and favorable safety profile strongly support its further clinical evaluation.", "source_company": "ARKGENBioScions", "source_org_type": "公司", "row_number": 118, "target_meta": "TROP2,HER2,CD3", "MOA_meta": "其他"}, {"drug_name": "BSI-551", "company": "Biosion Inc.", "org_type": "公司", "target": "PD-1, VEGF, CTLA-4", "modality": "bispecific antibody", "importance_level": "高", "total_score": 78.5, "institution_score": 75, "track_score": 90, "milestone_score": 65, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "BSI-551为新型PD-1×VEGF×CTLA-4三特异性抗体，靶向热门IO通路组合，设计上减弱CTLA-4亲和力以改善安全性。Biosion作为国内具有全球合作和临床管线的biotech机构，三特异抗体+IO热门组合赛道热度高，preclinical显示优于三药联用肿瘤退缩但仍处早期阶段。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4514", "id": "c1XM_5wBX1NQZOEH-LS6", "source_drug_name": "BSI-551", "title": "A novel PD-1xVEGFxCTLA-4 tri-specific antibody, BSI-551, demonstrates potent efficacy and favorable safety in preclinical tumor models", "abstract_text": "Background: Dual blockade of PD-1 with either CTLA-4 or VEGF has demonstrated superior efficacy over monotherapy. While PD-1/VEGF combinations improve progression-free survival, adding CTLA-4 blockade is critical to amplify initial and sustained T-cell activation. We hypothesized that a triple blockade could convert this potent disease control into a sustained, long-term survival benefit. Therefore, we developed BSI-551, a novel tri-specific antibody designed to simultaneously target PD-1, VEGF, and CTLA-4. Here, we report the development and preclinical activity of this new therapeutic.\nMethods: BSI-551 was generated based on the sequences of in-house PD-1 antibody BSI-050, anti-VEGF antibody ranibizumab, and anti-CTLA-4 antibody tremelimumab. Its binding affinity for human and cynomolgus monkey PD-1, VEGF-A, and CTLA-4 was assessed using surface plasmon resonance and flow cytometry. Blockade activity for PD-1 and VEGF was determined using NFAT-Jurkat-PD-1 and H-VEGF/293 reporter cell lines, respectively, while CTLA-4 blockade activity was evaluated in a Jurkat and GS-C1/CD80 co-culture system. The mixed lymphocyte reaction (MLR) assay was conducted using PBMCs from different donors with varying CD4/CD8 ratios. In vivo efficacy of BSI-551 was assessed in HT-29 (CRC) cell-derived xenograft (CDX) models in PBMC-humanized mice. Inflammatory cytokine levels were evaluated following co-culture with healthy donor PBMCs or after a single dose in humanized mice.\nResults: BSI-551 is a pentavalent molecule engineered with balanced targeting of PD1, VEGF, and CTLA4, and a half-life-extending YTE Fc mutation. It demonstrated strong binding affinity to both human and cynomolgus monkey PD1 and VEGF, which translated to potent cell-based blocking activity (sub-nanomolar IC50) in reporter assays. As intended by its design, BSI-551 showed attenuated binding affinity and blocking activity against CTLA4, a feature intended to avoid peripheral Treg inhibition and related toxicities. In functional MLR assays, BSI-551 induced T-cell activation, measured by IL2 release, and led to a dramatic decrease in PD1-positive T-cell subpopulations. Encouragingly, no significant release of inflammatory cytokines was observed in PBMC-based assay. In a CRC cancer model (HT-29), treatment with BSI-551 resulted in a significant tumor regression and better tumor growth inhibition (TGI) as compared to combo treatment of pembrolizumab, ipilimumab and bevacizumab.\n  Conclusion: In conclusion, BSI-551 demonstrates significant potential as a next-generation I/O therapy designed to be effective in tumors with poor responses to current monotherapies. Further pharmacokinetics, toxicity, and IND-enabling studies of BSI-551 are underway.", "source_company": "Biosion Inc.", "source_org_type": "公司", "row_number": 119, "target_meta": "PD1,CTLA4", "MOA_meta": "双特异性抗体"}, {"drug_name": "BH4601", "company": "Beijing Hanmi Pharm. Co. Ltd.", "org_type": "公司", "target": "PD-L1 and B7-H3", "modality": "ADC", "importance_level": "高", "total_score": 78.5, "institution_score": 75, "track_score": 90, "milestone_score": 60, "field_heat_score": 85, "bonus_score": 3, "brief_reason": "BH4601为四价PD-L1/B7-H3双特异性ADC，搭载Topo1抑制剂，靶向实体瘤；北京韩美为韩美制药中国子公司，母公司韩美在韩国制药行业具较强地位且R&D活跃，ADC+热门双靶点+双靶免疫调控机制具较高赛道热度，preclinical显示良好体内外活性及T细胞激活。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8770", "id": "plXM_5wBX1NQZOEH-LO6", "source_drug_name": "BH4601", "title": "Preclinical evaluation of BH4601, a novel tetravalent PD-L1 and B7H3 bispecific antibody-drug conjugate (ADC) with Topo1 inhibitor for the treatment of solid tumors", "abstract_text": "PD-L1 and B7-H3, members of the B7 superfamily, are frequently overexpressed across various tumor types. While antibody-drug conjugates (ADCs) targeting either PD-L1 or B7-H3 individually have demonstrated modest clinical efficacy, their co-expression in multiple malignancies presents a compelling rationale for dual-targeting strategies. This bispecific approach broadens the scope of tumor targeting and simultaneously alleviates T-cell suppression, potentially leading to enhanced therapeutic efficacy. The dual-targeting strategy addresses the compensatory upregulation observed between these targets—where suppression of B7-H3 leads to PD-L1 upregulation, and vice versa.\nA novel bispecific antibody concurrently targeting PD-L1 and B7-H3 was conjugated with a topoisomerase I inhibitor (XYD-295) and BH4601 was generated. In vitro evaluations revealed that BH4601 exhibits excellent target binding and internalization activities, as well as potent PD-1/PD-L1 blockade. Effective tumor control was demonstrated in multiple in vivo models, accompanied by significant T-cell activation. All animals remained well-tolerated at efficacious dose levels.\nBy simultaneously engaging both PD-L1 and B7H3 pathways, BH4601 achieves enhanced tumor-specific distribution and efficient tumor cell internalization, potentially improving both efficacy and safety profiles compared to its parental ADCs.", "source_company": "Beijing Hanmi Pharm. Co. Ltd.", "source_org_type": "公司", "row_number": 132, "target_meta": "PDL1,CD276", "MOA_meta": "抗体偶联药物"}, {"drug_name": "²¹²Pb-PS0001", "company": "AdvanCell Pty Ltd", "org_type": "公司", "target": "PSMA", "modality": "RLT imaging agent", "importance_level": "高", "total_score": 78.5, "institution_score": 75, "track_score": 90, "milestone_score": 60, "field_heat_score": 85, "bonus_score": 3, "brief_reason": "靶向PSMA的²¹²Pb标记放射性配体疗法（TAT/RLT），在免疫完整前列腺癌模型中显示出强效抗肿瘤活性及潜在免疫调节作用。AdvanCell作为专注靶向α疗法的临床阶段biotech，赛道热度高（α粒子RLT+PSMA热门），但本条为tool compound的preclinical研究，里程碑相对早期。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5341", "id": "PFXM_5wBX1NQZOEH-LS6", "source_drug_name": "²¹²Pb-PS0001", "title": "Evaluation of ²¹²Pb-PSMA radioligand therapy in an immunocompetent prostate cancer model", "abstract_text": "Introduction: Prostate cancer (PC) is the second leading cause of cancer-related death in men, and metastatic castration-resistant prostate cancer (mCRPC) remains incurable. Prostate-specific membrane antigen (PSMA) is a validated therapeutic target. Targeted alpha therapies (TAT) employing radionuclides such as lead-212 (²¹²Pb) and actinium-225 (²²⁵Ac) are in development, delivering high-linear-energy-transfer radiation with potent cytotoxic and potentially immunomodulatory effects. However, currently available PSMA-positive preclinical models rely on human xenografts, which do not allow for the study of radioligand therapy-induced immune modulation.\nObjective: The immunomodulatory effects of PSMA-targeted alpha therapy are believed to play a key role in the anti-tumor efficacy towards PC. However, the lack of immunocompetent in vivo models of PSMA-positive PC has been a major hurdle in mechanistic and translational studies. To overcome this, we established a syngeneic prostate cancer model expressing murine PSMA (mPSMA) and developed a high-affinity PSMA-directed TAT tool compound specific to mPSMA.\nMethodology: Murine bone-metastatic prostate cancer cell line, RM1-BM, which recapitulates late-stage TP53-mutant disease, was engineered to express murine FOLH1 (mPSMA) using the PiggyBac transposon system. Expression of mPSMA was confirmed both in vitro and in vivo by western blotting and immunohistochemistry. The affinity and specificity of the TAT agent ²¹²Pb-PS0001 (AdvanCell) for murine and human PSMA were assessed using inhibition and cytotoxicity assays. Biodistribution and therapeutic efficacy were assessed in immunocompetent C57BL/6 mice bearing mPSMA-RM1-BM tumors. Blood and tissue samples collected from treated animals underwent multiomics analyses to characterize immune response modulation induced by ²¹²Pb-PS0001.\nResults: RM1-BM-mFOLH1 cells expressed mPSMA at levels comparable to human PSMA-positive C4-2 cells. ²¹²Pb-PS0001 exhibited high-affinity, selective binding and robust tumor uptake in RM1-BM-mFOLH1 models, with minimal off-target accumulation. Therapeutic evaluation demonstrated that a single administration of ²¹²Pb-PS0001 significantly inhibited RM1-BM-mFOLH1 tumor growth in immunocompetent mice, whereas untreated controls showed progressive disease. Notably, several treated animals achieved durable tumor control, suggesting potential induction of an anti-tumor immune response.\nConclusion: By establishing a syngeneic, mPSMA-positive metastatic prostate cancer model, we enabled the evaluation of PSMA-TAT in an immunocompetent setting. Preliminary studies with ²¹²Pb-PS0001 demonstrated selective PSMA targeting, favorable pharmacokinetics, and potent anti-tumor efficacy, supporting its utility as a PSMA-TAT tool compound for investigating immune-mediated mechanisms of action in prostate cancer.", "source_company": "AdvanCell Pty Ltd", "source_org_type": "公司", "row_number": 158, "target_meta": "PSMA", "MOA_meta": "其他"}, {"drug_name": "BCG048", "company": "Biocytogen", "org_type": "公司", "target": "ITGB6 和 B7H3", "modality": "bispecific ADC", "importance_level": "高", "total_score": 78.5, "institution_score": 70, "track_score": 95, "milestone_score": 60, "field_heat_score": 85, "bonus_score": 8, "brief_reason": "BCG048为Biocytogen开发的双靶点（ITGB6×B7-H3）双payload bispecific ADC，靶点组合新颖且针对实体瘤异质性，modality属于ADC热门赛道中的高热度分支。机构为国内知名biotech平台型公司、赛道与机制亮点突出、PDX模型显示potent efficacy，preclinical阶段但具first-in-class潜力。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11407", "id": "D1XM_5wBX1NQZOEH-LO6", "source_drug_name": "BCG048", "title": "BCG048, a novel bispecific dual-payload ADC targeting ITGB6 and B7H3, exhibited potent efficacy in patient-derived tumor xenograft models", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Biocytogen", "source_org_type": "公司", "row_number": 169, "target_meta": "CD276,ITGB6", "MOA_meta": "抗体偶联药物"}, {"drug_name": "CTPH-08", "company": "Celltrion Pharm, Inc.", "org_type": "公司", "target": "FRα", "modality": "ADC", "importance_level": "高", "total_score": 78.5, "institution_score": 75, "track_score": 90, "milestone_score": 65, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "CTPH-08为靶向FRα的双payload ADC，旨在改善低表达卵巢癌患者的治疗窗和疗效；Celltrion Pharm作为韩国头部生物制药集团旗下公司，ADC尤其是dual-payload为当前热门赛道，preclinical数据扎实并计划推进至PDX和GLP毒理，综合潜力较高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5370", "id": "2lXM_5wBX1NQZOEH-LG6", "source_drug_name": "CTPH-08", "title": "A novel synergistic dual-payload FRα ADC (CTPH-08) that can potentially offer benefits for low IHC+ ovarian cancer patients by improving MTD and MED", "abstract_text": "Dual-payload antibody drug conjugates (ADCs) have achieved increasing traction as a next-generation ADC technology to improve the therapeutic window of single-payload ADCs. By integrating two different payloads having distinct modes of actions, dual-payload ADC platforms can offer opportunities to counter tumor heterogeneity, or to reduce the likelihood of resistance that often emerges with the single-payload ADCs. We have pursued novel dual-payload ADC formats that can provide synergistic activity as well as minimal overlapping toxicity due to complementary acting mechanisms from two different payloads. A few combinations of payloads have been found to demonstrate synergistic cytotoxicity, which have been successfully incorporated into ADCs to confirm the novel dual-payload ADC(AD2C) concept. Although folate receptor-alpha (FRα) represents a clinically validated antigen as highlighted by the approval of Elahere, clinical benefit is yet to remain limited due to dose-limiting toxicities and suboptimal response durability. To address these shortcomings, we have generated dual-payload FRα ADC (AD2C) designed to enhance anti-tumor activity without exacerbating systemic toxicity. This presentation covers a comprehensive characterization of FRα AD2C including in vitro cytotoxicity for cancer cells with different levels of FRα expression, in vivo anti-tumor activities in FRα-positive CDX models, in vivo stability of FRα AD2C via pharmacokinetic assessment in rats, and preliminary safety evaluation in mice. We are currently advancing dual-payload FRα ADC(AD2C) toward PDX efficacy studies and GLP toxicology studies in order to proceed to Ph1 IND filing in due course.", "source_company": "Celltrion Pharm, Inc.", "source_org_type": "公司", "row_number": 201, "target_meta": "FOLR1", "MOA_meta": "抗体偶联药物"}, {"drug_name": "SCN-PYTA", "company": "Convergent Therapeutics, Inc.", "org_type": "公司", "target": "未披露", "modality": "BFC", "importance_level": "高", "total_score": 78.5, "institution_score": 75, "track_score": 85, "milestone_score": 70, "field_heat_score": 90, "bonus_score": 3, "brief_reason": "SCN-PYTA是一种新型双功能螯合剂（BFC），用于三价放射性金属（如225Ac、177Lu）的快速室温螯合，比DOTA更优越，适用于开发靶向放射性药物。Convergent Therapeutics作为专注α放射抗体的临床阶段biotech公司，赛道为热门RLT领域且展示优异螯合性能和稳定性，综合潜力较高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3893", "id": "1lXM_5wBX1NQZOEH-LG6", "source_drug_name": "SCN-PYTA", "title": "SCN-PYTA: A new bifunctional chelator (BFC) for trivalent radiometals to develop target-specific radiopharmaceuticals for imaging and therapy", "abstract_text": "Introduction: The 18-membered macrocycle PYTA is a universal chelator that can complex trivalent radiometals (e.g., 225Ac, 177Lu, 111In and 44Sc) useful for imaging and targeted therapy (Chemical Sci 2024;15:11279-11286). The investigators at ORNL synthesized a BFC, SCN-PYTA, which contains an amine-reactive thiocyanate (SCN) group appended to the pyridine in the PYTA chelator. To establish PYTA as a platform to prepare theranostic radiopharmaceuticals, we investigated the conjugation characteristics of SCN-PYTA to monoclonal antibodies (mAb) and radiometals (111In and 225Ac) to define the chelation properties of PYTA-mAb conjugates. For direct comparison, labeling studies were performed using two other BFCs: SCN-DOTA and SCN-Macropa.\nMaterials and Methods: Anti-PSMA mAb, rosopatamab and anti-TROP-2 mAb, sacituzumab solutions at 10 mg/mL were prepared in sodium carbonate buffer, pH 9.0±0.2. The BFC solutions (at 5-10 mg/mL) were prepared in metal-free water. Different molar ratios of BFC to mAb were incubated at 37oC for 90 min. The chelate conjugated mAbs were purified by gel chromatography and 0.05 M HEPES buffer, pH 7.5. The chelator:antibody ratios (CAR) were determined using a modified colorimetric arsenazo assay. Chelate-antibody conjugates (0.025-2.0 mg) were incubated (at RT or 37oC) with 0.05-0.5 mCi of 225Ac or 111In chloride in sodium acetate or tetramethylammonium acetate buffer, pH 6±0.3. Radiolabeled mAbs were purified using PD-10 gel permeation chromatography and saline solution containing 1% albumin, and assessed for radiochemical purity (RCP), stability, and immunoreactivity.\nResults: PYTA and Macropa conjugated mAbs complex 225Ac or 111In radionuclides very efficiently at RT within 5 min with labeling yields of >97%. The radiochemical purity (RCP) of purified 225Ac-chelator-mAb preparations were >99%. In contrast, DOTA-conjugated mAbs do not label efficiently at RT. Higher labeling yield (80-95%), however, can be obtained at 37oC with longer incubation of 1-2 hours. 225Ac-PYTA-mAbs showed remarkably high in vitro stability at 2-8oC for >10 days (with >99% RCP). Similar stability was observed when challenged with serum or excess chelate (EDTA and DTPA) concentrations. Based on in vitro cell binding studies using PSMA+ LNCaP cells and TROP-2+ MCF-7 cells, the immunoreactive fraction (IRF) of 225Ac-PYTA-Rosopatamab and 225Ac-PYTA-Sacituzumab at an infinite antigen concentration (Lindmo assay) was >99%.\nConclusion: SCN-PYTA is an ideal BFC and a suitable platform to develop target specific imaging and therapeutic radiopharmaceuticals based on trivalent radiometals, peptides, proteins, and small molecules. Our preliminary data also suggests that radiolabeled sacituzumab has significant potential as a theranostic radiopharmaceutical for imaging and targeted therapy of TROP-2 positive cancers.", "source_company": "Convergent Therapeutics, Inc.", "source_org_type": "公司", "row_number": 288, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "tumor-targeted bispecific antibodies", "company": "Genentech, Inc.", "org_type": "公司", "target": "未披露", "modality": "bispecific antibody", "importance_level": "高", "total_score": 78.5, "institution_score": 95, "track_score": 90, "milestone_score": 30, "field_heat_score": 85, "bonus_score": 3, "brief_reason": "Genentech开发的肿瘤靶向双特异性抗体，强调有效抑制癌基因通路同时最小化毒性，但摘要被禁未披露具体靶点和机制细节。机构顶级（高分），双抗赛道热门且聚焦肿瘤特异性+低毒性（高分），但因preclinical阶段且信息极少里程碑分低，总分仍达高重要性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11575", "id": "NFXM_5wBX1NQZOEH-LG5", "source_drug_name": "tumor-targeted bispecific antibodies", "title": "Tumor-targeted bispecific antibodies effectively inhibit oncogenic pathways while minimizing toxicity", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Genentech, Inc.", "source_org_type": "公司", "row_number": 344, "target_meta": "not available", "MOA_meta": "双特异性抗体"}, {"drug_name": "a novel bifunctional compound designed to selectively degrade MCL-1", "company": "Captor Therapeutics S.A.", "org_type": "公司", "target": "MCL-1", "modality": "degrader", "importance_level": "高", "total_score": 78.5, "institution_score": 65, "track_score": 90, "milestone_score": 80, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "靶向MCL-1的双功能降解剂（degrader），通过选择性降解避免抑制剂的心脏毒性积累，具有心安优势。机构为欧洲专注TPD的中小型上市biotech，赛道热门（TPD+血液瘤高需求靶点），preclinical数据强劲并进入IND/CTA阶段，支持较高综合重要性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8713", "id": "UlXM_5wBX1NQZOEH-LG5", "source_drug_name": "a novel bifunctional compound designed to selectively degrade MCL-1", "title": "Preclinical evaluation of a cardiosafe first-in-class MCL-1 degrader for the treatment of hematological malignancies", "abstract_text": "MCL-1, a member of the Bcl-2 family of apoptosis regulators, is a critical pro-survival factor implicated in tumor maintenance and therapeutic resistance across a wide range of cancers. Although several MCL-1 inhibitors have entered clinical development, many were discontinued due to dose-limiting cardiac toxicity. Targeted protein degradation offers an alternative strategy with potential advantages, including improved selectivity, prolonged pharmacodynamic effects, and reduced risk of adverse cardiac events.\nHere, we describe the discovery and preclinical characterization of a novel bifunctional compound designed to selectively degrade MCL-1 for the treatment of hematological malignancies. Biophysical assays confirmed ternary complex formation between the degrader, MCL-1, and an E3 ligase. The compound induces proteasome-dependent degradation of MCL-1, leading to apoptosis and cell death in a broad panel of human cancer cell lines, with low nanomolar potency (pIC₅₀ ~9 for MV4-11, OPM-2, and DMS114). Cytotoxic effects were observed across leukemia, lung cancer, and multiple myeloma models, while sparing normal and primary cells. In human iPSC-derived cardiomyocytes, the degrader caused only transient reduction of MCL-1 levels, in contrast to MCL-1 inhibitors that induced 6-15-fold MCL-1 upregulation persisting after washout, a mechanism linked to elevated cardiac troponin in clinical trials.\nIn vivo, the compound demonstrated strong antitumor activity in AML xenograft models, inducing MCL-1 degradation and tumor growth inhibition. Combination with low-dose venetoclax (7.5 mpk) promoted tumor regression at 5 mpk using an intermittent dosing regimen (2 days on/5 days off). In non-human primates, the compound exhibited a favorable pharmacokinetic/pharmacodynamic profile with effective MCL-1 degradation and no evidence of cardiac toxicity at exposures exceeding predicted human efficacious levels.\nIn conclusion, we have developed a highly potent and selective bifunctional MCL-1 degrader that shows robust activity in vitro and in vivo, complete target coverage, and a favorable safety margin compared with MCL-1 inhibitors. These findings support MCL-1 degradation as a promising therapeutic approach for hematologic malignancies. The compound is advancing through IND/CTA-enabling studies, with a first-in-human Phase 1 trial planned for 2026.", "source_company": "Captor Therapeutics S.A.", "source_org_type": "公司", "row_number": 367, "target_meta": "MCL1", "MOA_meta": "降解剂"}, {"drug_name": "molecular glue", "company": "WuXi AppTec", "org_type": "公司", "target": "未披露", "modality": "molecular glue", "importance_level": "高", "total_score": 78.5, "institution_score": 75, "track_score": 90, "milestone_score": 65, "field_heat_score": 85, "bonus_score": 3, "brief_reason": "分子胶属于热门TPD领域新型模态，靶点未明确披露但聚焦非CRBN新型E3连接酶挖掘，具有平台性和机制创新潜力。WuXi作为全球知名CRO/CDMO机构在早期工具化合物库构建和多组学验证方面展现较强技术实力，赛道热度高但仍处平台技术探索阶段故综合评分为高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8739", "id": "c1XM_5wBX1NQZOEH-LG5", "source_drug_name": "molecular glue", "title": "Novel non-CRBN based molecular glue identification and corresponding E3 ligase target deconvolution through multi-omics analysis", "abstract_text": "Targeted Protein Degradation (TPD) is considered one of the new drug discovery strategies that could address previously “undruggable” disease targets through the ubiquitin-proteasome system (UPS). Although the current Target Protein Centric approach has proven successful in many cases, especially with well-validated E3 ligases such as CRBN and VHL, there is still a strong need to identify potential target protein degraders (PROTACs, molecular glues, etc.) through both target-centric and target-agnostic approaches. This would not only explore and identify potential tissue-specific novel E3 ligases but also greatly expand the range of potential degradable disease targets. In this study, we first developed a molecular glue-focused library consisting of approximately 5,000 compounds through various medicinal chemistry evaluations. A GSPT1-HiBit cell line and a GSPT1-CRBN-KO counter cell line were developed for primary hit screening purposes. More than 100 potential hits were identified through the initial screening, which included both CRBN-dependent and CRBN-independent hits. A GSPT1-based proximity labeling cell line was then constructed for further target deconvolution purposes via proteomics. Potential candidate E3 ligases were subsequently validated using an array-based expression manipulation strategy. Additionally, we tested novel synthetic lethal target discovery through both in vitro and in vivo screens, followed by omics-based target validation. Using a CRBN-focused glue library, we combined both transcriptomics and proteomics assays to evaluate potential “degradable” targets. To sum up, our study demonstrates that integrated target discovery and target deconvolution strategies could be useful for TPD drug discovery as well as other disease scenarios.", "source_company": "WuXi AppTec", "source_org_type": "公司", "row_number": 387, "target_meta": "not available", "MOA_meta": "分子胶"}, {"drug_name": "pMHC directed TCEs", "company": "T-Therapeutics Ltd", "org_type": "公司", "target": "pMHC", "modality": "TCE", "importance_level": "高", "total_score": 78.5, "institution_score": 75, "track_score": 90, "milestone_score": 65, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "靶向pMHC的TCE，利用TCR-like高亲和力特异性识别细胞内源肽，解决实体瘤和自身免疫病表面靶点稀缺难题。机构为Cambridge spin-out的TCR biotech，获Sofinnova等顶级VC近$91M A轮融资，平台技术先进且探索500+格式，赛道为热门TCE+新型pMHC靶点，preclinical阶段但具first-in-class潜力。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4294", "id": "0FXM_5wBX1NQZOEH-LK6", "source_drug_name": "pMHC directed TCEs", "title": "Unlocking pMHC target space for next generation T cell engagers in oncology and autoimmunity", "abstract_text": "Peptide-MHC (pMHC) complexes represent a compelling and emerging class of targets for oncology and autoimmune diseases. Their presentation on the cell surface enables the targeting of peptides from non-membrane bound proteins which could be highly specific to pathogenic cells. The lack of disease cell-surface specific targets is currently limiting the potential of bispecific T cell engagers (TCEs) for solid tumours and autoimmune diseases. Despite their promise, pMHC targeting TCEs face two significant challenges. Firstly, a pMHC targeting entity needs to bind to the pMHC of interest with high affinity and specificity to ensure drug efficacy and safety. Secondly, since cell surface density of pMHC is generally low (typically ~10 -1,000 copies per cell), the bispecific format and anti-CD3 moiety need to work concordantly to mediate efficient killing with minimal cytokine release. We have developed unique technology platforms to overcome these major challenges for delivering first-in-class pMHC directed TCEs for solid tumours and autoimmunity. To harness the natural ability of TCRs to bind pMHC with high specificity and overcome the constraints for TCR discovery against self antigens in humans due to negative selection in T cell development, we generated a humanised transgenic mouse, OptiMus® mouse, by introducing human TCRα, TCRβ, CD8α, CD8β, HLA- A02, and β2M genes in situ by precision genome engineering. Over a decade, 1.6 million bases of human DNA were introduced into the mouse to fully humanise the entire TCRαβ repertoire, CD8 co-receptor and MHC class I. The immune compartment of this mouse strain is phenotypically normal, and importantly, it allows TCR discovery against human antigens without the self-antigen constraint. The diverse TCR repertoire produced by OptiMus® mouse enables the discovery of hundreds of antigen-reactive TCRs as a starting point for drug discovery. Drug efficacy at low pMHC target density requires a TCE format that is optimised for immune synapse engagement. The anti-CD3 moiety must be fine-tuned in terms of epitope selection and affinity modulation to maximize the therapeutic window. We have explored over 500 formats to identify a novel design in which a TCR, anti-CD3 and Fc are accommodated to allow efficient immune synapse formation and target cell killing, and which has an antibody-like developability and pharmacokinetics profile. Furthermore, we discovered de novo anti-CD3 moieties that are optimised with our format for desired properties: durable serial killing, high in vivo potency, low cytokine release and no T cell mediated drug disposition. By maximising the power of our technology platforms, from human TCR discovery to TCE engineering, we are advancing a pipeline of first-in-class TCEs for oncology and autoimmune indications. Our approach unlocks previously inaccessible targets and redefines the potential of TCEs in precision immunotherapy.", "source_company": "T-Therapeutics Ltd", "source_org_type": "公司", "row_number": 622, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "EpiTAC-ADC", "company": "EpiBiologics", "org_type": "公司", "target": "c-MET", "modality": "bispecific degrader ADC", "importance_level": "高", "total_score": 78.5, "institution_score": 75, "track_score": 90, "milestone_score": 65, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "EpiTAC-ADC为c-MET的bispecific degrader ADC，结合蛋白降解与细胞毒payload递送，新型双机制克服现有c-MET疗法耐药和低表达局限。机构为国外有107M Series B融资、GV与J&J领投的头部新兴biotech，热门extracellular degradation+ADC赛道+preclinical强活性数据故高分。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5397", "id": "71XM_5wBX1NQZOEH-LK6", "source_drug_name": "EpiTAC-ADC", "title": "Dual modality of EpiTAC bispecific degrader ADCs combines c-MET degradation with cytotoxic payload delivery to overcome limitations of current c-MET-targeted therapies", "abstract_text": "Extracellular targeted protein degradation (eTPD) is a new therapeutic modality designed to eliminate pathogenic extracellular and transmembrane proteins by leveraging proteosome and endosomal-lysosomal protein degradation pathways. EpiTACs are bispecific antibody-based eTPD therapeutics in which one arm binds to a pathogenic target protein and the other arm binds to a tissue-enriched degrading receptor to drive selective and potent protein removal. For the oncogenic receptor tyrosine kinase cMET, existing therapies such as tyrosine kinase inhibitors (TKIs) and antibody-drug conjugates (ADCs) face limitations due to acquired resistance or off-target toxicities and dependence on high target expression in the case of ADCs. We developed EpiTACs and EpiTAC-ADCs to cMET to overcome these challenges using a novel mutation-independent mechanism of action to degrade oncogenic cMET and deliver a cytotoxic payload to drive deep, durable and broad responses across cMET tumors. We screened a panel of cancer-focused degrading receptors in cMET exon 14 skipping mutant and wild type amplified tumor cell-based assays and identified potent cMET-degrading EpiTACs that drove internalization and degradation independent of form in multiple tumor cell-based assays. Degradation of mutant cMET in vitro translated to strong tumor growth suppression in vivo, but not all tumor cell models responded to degradation alone. We developed EpiTAC-ADCs to solve for tumors that express cMET but do not rely exclusively on its oncogenic signaling. EpiTAC-ADCs demonstrated robust anti-tumor activity in vitro and in vivo xenograft tumor models, including cMET responsive and non-responsive models. Combining protein degradation with cytotoxic payload delivery induced strong anti-tumor activity against models with low cMET, where standard ADCs are ineffective. The dual mechanism of EpiTAC-ADCs also demonstrates robust activity at lower drug-antibody ratio (DAR), independent of cMET expression levels or oncogenic signaling dependence. EpiTAC-ADCs represent a novel class of eTPD therapeutics that can effectively degrade oncogenic receptors including cMET independent of mutation and form, while delivering a potent cytotoxic payload. This approach has the potential to address oncogenic driver and resistance mechanisms broadly across cMET-driven tumors. In addition to targeting cMET-high tumors, EpiTAC-ADCs have the potential to target low and medium cMET tumors in patients whose needs are not addressed by standard of care therapeutics including ADCs.", "source_company": "EpiBiologics", "source_org_type": "公司", "row_number": 643, "target_meta": "c-Met", "MOA_meta": "抗体偶联降解剂"}, {"drug_name": "antibody-drug conjugate targeting p300 and CBP", "company": "Novartis Biomedical Research, Inc.", "org_type": "公司", "target": "p300 and CBP", "modality": "ADC", "importance_level": "高", "total_score": 78.5, "institution_score": 95, "track_score": 90, "milestone_score": 30, "field_heat_score": 85, "bonus_score": 0, "brief_reason": "该ADC针对p300和CBP（表观遗传关键共激活因子），通过Novartis公司开发，属于热门ADC+新型靶点降解机制赛道，具有较高机构和赛道热度。但摘要embargoed，仅标题体现preclinical概念验证，无具体数据或里程碑进展，因此里程碑分较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11467", "id": "AFXM_5wBX1NQZOEH-LO6", "source_drug_name": "antibody-drug conjugate targeting p300 and CBP", "title": "Targeted degradation of p300 and CBP via antibody-drug conjugate in prostate cancer cells", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Novartis Biomedical Research, Inc.", "source_org_type": "公司", "row_number": 654, "target_meta": "CBP/EP300", "MOA_meta": "抗体偶联药物"}, {"drug_name": "a novel anti-PD-1×CTLA-4×VEGF tri-specific antibody", "company": "ShangHai Hengrui Pharmaceuticals Co., Ltd.", "org_type": "公司", "target": "PD-1/CTLA-4/VEGF", "modality": "bispecific antibody", "importance_level": "高", "total_score": 78.5, "institution_score": 85, "track_score": 95, "milestone_score": 40, "field_heat_score": 90, "bonus_score": 3, "brief_reason": "该三特异性抗体靶向PD-1、CTLA-4和VEGF，属于热门的多靶点免疫检查点+抗血管生成赛道，具有肿瘤选择性阻断和强效抗瘤活性的机制亮点。恒瑞作为国内头部药企机构实力强，但摘要被embargo且仅preclinical水平导致里程碑分较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11543", "id": "z1XM_5wBX1NQZOEH-LO6", "source_drug_name": "a novel anti-PD-1×CTLA-4×VEGF tri-specific antibody", "title": "A novel anti-PD-1×CTLA-4×VEGF tri-specific antibody enables tumor-selective immune checkpoint blockade with potent anti-tumor activity", "abstract_text": "Abstract is embargoed at this time.", "source_company": "ShangHai Hengrui Pharmaceuticals Co., Ltd.", "source_org_type": "公司", "row_number": 797, "target_meta": "PD1,CTLA4", "MOA_meta": "双特异性抗体"}, {"drug_name": "RIPTACs", "company": "Halda Therapeutics", "org_type": "公司", "target": "未披露", "modality": "other", "importance_level": "高", "total_score": 78.5, "institution_score": 85, "track_score": 95, "milestone_score": 30, "field_heat_score": 90, "bonus_score": 5, "brief_reason": "RIPTACs为新型异双功能小分子，通过'hold-and-kill'机制诱导肿瘤特异蛋白与必需蛋白接近，实现选择性杀伤癌细胞，属于诱导接近热门赛道；摘要无任何具体靶点或开发阶段披露，导致里程碑分较低，但Halda作为创新biotech且平台机制新颖，整体潜力高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/580", "id": "BVXM_5wBX1NQZOEH-LS6", "source_drug_name": "RIPTACs", "title": "RIPTACs: A novel, powerful modality to treat patients with prostate cancer and other diseases", "abstract_text": "There is no abstract associated with this presentation.", "source_company": "Halda Therapeutics", "source_org_type": "公司", "row_number": 833, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "S-DUAL™", "company": "Samsung Biologics", "org_type": "公司", "target": "HER2", "modality": "bispecific antibody", "importance_level": "高", "total_score": 78.5, "institution_score": 75, "track_score": 90, "milestone_score": 65, "field_heat_score": 85, "bonus_score": 3, "brief_reason": "基于Samsung Biologics的S-DUAL™平台开发的双特异性抗体，同时靶向HER2的II和IV结构域以克服HER2过表达或截短导致的耐药。机构实力较强、双抗+HER2赛道热度高、在体外/体内模型显示优于传统抗体的信号抑制和抑瘤效果，综合重要性较高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11075", "id": "i1XM_5wBX1NQZOEH-LS6", "source_drug_name": "S-DUAL™", "title": "S DUAL™: An Advanced Bispecific Antibody Platform Delivering Practical Manufacturability and Enhanced Therapeutic Efficacy", "abstract_text": "Background - Receptor tyrosine kinases (RTKs) drive tumor progression through ligand‑dependent or ligand‑independent dimerization, which brings the intracellular kinase domains into proximity, triggers autophosphorylation, and recruits adaptor proteins such as GRB2 and Shc. The resulting RAS‑MAPK and PI3K‑AKT cascades sustain cancer cell proliferation, survival and differentiation. Among RTKs, HER2 (ErbB2) is an orphan receptor that preferentially forms homodimers and heterodimers with other ErbB family members. HER2 over‑expression or the generation of truncated forms (e.g., p95HER2) is strongly associated with aggressive disease and resistance to HER2‑directed therapies.\nClinically - approved HER2 antibodies—trastuzumab (domain IV) and pertuzumab (domain II)—bind distinct extracellular epitopes yet only partially inhibit HER2‑driven signaling, especially in tumors with high HER2 density or in which the receptor is mutated/truncated. Consequently, patients often develop intrinsic or acquired resistance.\nApproach - To overcome these limitations, we employed Samsung Biologics’ S‑DUALTM platform to generate a heterodimeric bispecific antibody (BsAb) that simultaneously engages HER2 epitopes II and IV. The two Fab arms are engineered to heterodimerize via a “knob‑into‑hole” Fc architecture, preserving native IgG1 Fc effector function while enforcing defined Fab geometry.\nResults - In HER2‑positive cell lines, S‑DUALTM reduced HER2 autophosphorylation by ~27.9 % (p < 0.05) and downstream p‑ERK1/2 and p‑AKT levels by 18.6 % and 25.3 %, respectively, resulting in a maximal inhibition (Emax) of 64.4 % in cell proliferation (IC50 ≈ 1.64 nM). Cell surface binding affinity and Fc‑mediated ADCC activity remained comparable to reference platform. In HER2‑positive xenograft models, weekly intravenous administration of S‑DUALTM substantially reduced tumor growth relative to the isotype control, achieving a marked suppression of tumor volume without evident toxicity.\nConclusion - Simultaneous blockade of two non‑overlapping HER2 extracellular domains by a biparatopic BsAb can fully suppress ligand‑independent HER2 signaling while preserving immune effector mechanisms. This “dual‑epitope, Fab‑geometry‑tuned” strategy defines a new design principle for next‑generation HER2 therapeutics and offers a potential solution to overcome resistance arising from HER2 over‑expression, truncation, or mutation.", "source_company": "Samsung Biologics", "source_org_type": "公司", "row_number": 932, "target_meta": "HER2", "MOA_meta": "双特异性抗体"}, {"drug_name": "selective ARID1B degraders", "company": "Foghorn Therapeutics", "org_type": "公司", "target": "ARID1B", "modality": "degrader", "importance_level": "高", "total_score": 78.5, "institution_score": 75, "track_score": 90, "milestone_score": 60, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "ARID1B degrader针对ARID1A突变癌症，利用合成致死机制降解此前认为不可成药的ARID1B，属于首创first-in-class。Foghorn为专注染色质调控的头部biotech公司，degrader赛道热度高但仍处preclinical早期向in vivo POC推进，综合潜力显著。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8745", "id": "uFXM_5wBX1NQZOEH-LS6", "source_drug_name": "selective ARID1B degraders", "title": "Identification of first in class selective ARID1B degraders", "abstract_text": "ARID1B, a core component of the SWI/SNF chromatin remodeling complex, has long been considered undruggable due to the absence of known binders and lack of ligandable pockets. Striking dependency on ARID1B is observed across multiple cancer indications harboring ARID1A mutations, including endometrial, ovarian, and gastric cancers. This highlights the synthetic lethal relationship between the two paralogs and establishes ARID1B as a high value target for precision oncology. We report the discovery and optimization of first in class selective ARID1B degraders for the treatment of ARID1A mutant cancers. Using our platform and structure based design, we first identified several selective ARID1B binder series, which were then used to develop VHL and CRBN based molecules that induce robust ARID1B degradation via the ubiquitin-proteasome system. These compounds exhibit on mechanism activity, high selectivity, and downstream transcriptional modulation. This work establishes ARID1B degradation as a promising therapeutic strategy and provides a blueprint for targeting previously intractable chromatin remodelers.", "source_company": "Foghorn Therapeutics", "source_org_type": "公司", "row_number": 967, "target_meta": "ARID1B", "MOA_meta": "降解剂"}, {"drug_name": "exatecan-based ADC", "company": "Crown Bioscience, Inc.", "org_type": "公司", "target": "TROP2", "modality": "ADC", "importance_level": "高", "total_score": 78.5, "institution_score": 65, "track_score": 90, "milestone_score": 75, "field_heat_score": 85, "bonus_score": 3, "brief_reason": "该exatecan-based ADC靶向TROP2，采用膜渗透性payload实现旁观者杀伤效应，在广泛的患者来源类器官模型中显示出高疗效和明确的靶点依赖性。Crown Bioscience作为知名肿瘤学CRO在preclinical平台上进行深入功能筛选，TROP2+ADC赛道热度高，研究展示清晰的机制验证和转化价值。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5429", "id": "ip7M_5wBZznHJdnt_W3O", "source_drug_name": "exatecan-based ADC", "title": "Functional organoid screening uncovers target dependency and bystander killing in TROP2 ADCs", "abstract_text": "Introduction: TROP2-targeted antibody-drug conjugates (ADCs) represent a promising therapeutic class for multiple tumor types with elevated TROP2 expression. Membrane-permeable payloads can induce bystander killing, making functional, physiologically relevant testing crucial. We developed an advanced organoid-based ADC evaluation workflow combining large-scale patient-derived (xenograft) organoid (PD(X)O) screening, CRISPR-engineered isogenic models, and 3D high-content imaging (HCI) to assess potency, target dependency, and bystander effects.\nMethods: Two TROP2 ADCs - an experimental exatecan-based ADC linked via a hydrophilic, cleavable linker, and datopotamab-deruxtecan (Dato-Dxd; DS‑1062) - were evaluated in the organoid screening platform, where models were selected irrespective of TROP2 expression. The exatecan-based ADC was tested in 109 PD(X)Os (101 tumor, 8 normal) across ten cancer types using nine-point dose-response. Dato-Dxd was screened using six-point dose-response assays in 142 PD(X)Os (132 tumor; 10 normal) spanning nine tumor types. Drug incubation ran over five days, and efficacy was determined by ATP-based cell viability assay. Free payloads exatecan and Dxd (both naked and linker-conjugated) served as controls. CRISPR/Cas9-generated TROP2 knockout (KO) organoid pairs were labeled with fluorescent/luminescent reporters for target HCI-based dependency and bystander effect assays.\nResults: The exatecan-based ADC demonstrated high overall efficacy (68.6% showed >50% inhibition at the highest dose of 1 µM), with pancreatic models even showing 100% sensitivity, and 32.4% of organoids achieving IC50 < 0.1 µM. Payloads alone were strongly cytotoxic in most models (93.3% of models sensitive with IC50 < 0.03 µM) with similar potency for exatecan and Dxd, whereas linker-conjugated Dxd was significantly less cytotoxic (average IC50 > 0.1µM). Dato-Dxd responses varied across the PD(X)O panel (54% showed >50% inhibition at 0.1µM, 37% IC50 < 0.1µM). For both TROP2 ADCs, a correlation between efficacy and TROP2 mRNA abundance was observed. In isogenic KO organoid models, loss of TROP2 abrogated Dato-Dxd responses, confirming target dependency. Mixed-culture assays quantified Dato-Dxd bystander killing, validating membrane-permeable payload action in neighboring cells.\nConclusion: The combined organoid screening and HCI workflow provides a robust, translationally relevant platform for ADC evaluation, integrating efficacy profiling, mechanistic validation, and functional bystander effect modeling. CRISPR-generated isogenic organoids enable precise dissection of target dependency and resistance, supporting the preclinical optimization of TROP2-targeted ADCs.", "source_company": "Crown Bioscience, Inc.", "source_org_type": "公司", "row_number": 1042, "target_meta": "TROP2", "MOA_meta": "抗体偶联药物"}, {"drug_name": "l-BPA-based dipeptides", "company": "TAE Life Sciences", "org_type": "公司", "target": "未披露", "modality": "other", "importance_level": "高", "total_score": 78.5, "institution_score": 75, "track_score": 80, "milestone_score": 80, "field_heat_score": 85, "bonus_score": 4, "brief_reason": "l-BPA-based dipeptides作为BNCT硼递送剂的改进型前药，针对l-BPA溶解度差的局限，实现更高剂量递送并在动物模型中诱导完全肿瘤消退及疫苗效应。TAE Life Sciences作为专注BNCT的国外头部biotech，赛道为新兴精准放疗+免疫激活，preclinical数据强且具突破性，总分较高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3959", "id": "_1XM_5wBX1NQZOEH-LC5", "source_drug_name": "l-BPA-based dipeptides", "title": "Highly soluble prodrug boronophenylalanine (L-BPA) dipeptide, exhibits notable tumor suppression whilst inducing cancer vaccine effect post neutron irradiation treatment", "abstract_text": "Boron Neutron Capture Therapy (BNCT) is an emerging cancer treatment modality that has seen a resurgence due to its efficacy and the advent of compact neutron beam devices. BNCT is a binary cancer treatment that combines selective boron delivery with epithermal neutron irradiation. When 10B-enriched compounds accumulate in tumor cells and capture low-energy neutrons, the reaction generates high-linear energy transfer (LET) α-particles and 7Li nuclei that deposit their energy within a few microns, producing irreparable DNA double-strand breaks and tumor cell death while sparing normal tissues. The clinical success of BNCT critically depends on the selective delivery of sufficient boron to tumors. Currently, 4- l-boronophenylalanine (l-BPA) is the leading BNCT agent, as it exploits LAT-1 (SLC7A5), a transporter highly expressed in many solid tumors. However, l-BPA suffers from poor solubility, severely limiting the maximum intravenous dose that can be administered and thereby constraining therapeutic efficacy. Here we report the synthesis and evaluation of highly soluble 10B-enriched l-BPA-based dipeptides as next-generation boron delivery agents. These dipeptides, incorporating hydrophilic peptide linkages, enabled substantially higher intravenous bolus doses in mice compared to l-BPA while maintaining favorable biodistribution. In vivo, the dipeptides were rapidly cleaved by endogenous proteases, releasing l-BPA de novo within tumors. Neutron irradiation of syngeneic CT26 tumors in dipeptide-treated mice produced complete and durable tumor regressions, accompanied by immunological effects including a vaccine response and abscopal tumor suppression. By contrast, l-BPA administered at its solubility-limited maximal dose and using the same irradiation produced only transient growth delay without durable regression or immune activation. These findings establish dipeptides as a promising strategy to overcome the solubility limitations of l-BPA, enabling higher boron delivery, improved tumor control, and immune-mediated benefits. This approach could significantly expand the therapeutic potential of BNCT.", "source_company": "TAE Life Sciences", "source_org_type": "公司", "row_number": 1289, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "DB-1323", "company": "Duality Biologics Ltd", "org_type": "公司", "target": "MSLN", "modality": "ADC", "importance_level": "高", "total_score": 78, "institution_score": 85, "track_score": 75, "milestone_score": 70, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "DB-1323为靶向MSLN的下一代ADC，采用新型抗体和拓扑异构酶I抑制剂有效克服了可溶性MSLN沉没效应和内化不足等历史难题，在胰腺癌和卵巢癌模型中显示优于对照ADC的抗瘤活性。Duality Biologics作为国内领先ADC biotech（与BioNTech合作、多款ADC进入临床III期、市值较高），ADC赛道热度高但MSLN靶点非最热门，preclinical数据扎实且有清晰差异化亮点，总分较高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4041", "id": "ClXM_5wBX1NQZOEH-LO6", "source_drug_name": "DB-1323", "title": "DB-1323, a next-generation mesothelin targeting antibody-drug conjugate, demonstrated anti-tumor activity and favorable safety profile in pre-clinical models", "abstract_text": "Background: Mesothelin (MSLN) is highly expressed in many hard-to-treat solid tumors and is associated with metastasis, poor progression-free survival and lower overall survival. Despite 25 years of drug- development efforts across modalities, no MSLN-directed therapy has been approved, hampered by on-/off-target toxicities, intra-tumoral antigen heterogeneity, poor internalization of MSLN-antibody complexes, and soluble MSLN “sink” effects. DB-1323 is a MSLN-ADC composed of a novel fully human anti-MSLN immunoglobulin G1 (IgG1) monoclonal antibody, covalently conjugated to a proprietary DNA topoisomerase I inhibitor via a maleimide-tetrapeptide cleavable linker. In the present study, we evaluated the efficacy and safety of DB-1323 in comprehensive preclinical models.\nMethods: Binding affinity of the anti-MSLN antibody to MSLN-expressing cells was quantified by flow cytometry. Cytotoxicity was assessed in MSLN-positive pancreatic cancer cells. Anti-tumor activity was tested in MSLN-positive pancreatic and ovarian cancer xenograft models compared to that of anetumab ravtansine and other MSLN ADCs. The pharmacokinetics and safety profile were also evaluated in cynomolgus monkeys.\nResults: DB-1323 showed high affinity to both Human and Cyno MSLN without detectable off-target binding. DB-1323 has unique MSLN binding characteristics (fast on/off kinetics) that allow it to evade soluble MSLN while maintaining high avidity for MSLN on the surface of tumor cells. DB-1323 has faster and more extensive internalization than anetumab ravtansine, especially in the presence of physiologically relevant soluble MSLN concentrations. In vitro, DB-1323 retained cytotoxicity towards MSLN-expressing pancreatic cancer cells in the presence of soluble MSLN. It also showed dose-dependent anti-tumor activity in a pancreatic cancer xenograft model and ovarian cancer patient-derived xenograft model. Moreover, DB-1323 showed stronger tumor growth inhibition than that of anetumab ravtansine at the same dose. The systemic exposure AUC0-last and Cmax of DB-1323 and total antibody increased dose proportionally from 1mg/kg to 10mg/kg with low free payload in serum. DB-1323 also showed good safety profile with highest non-severely toxic dose (HNSTD) of 60mg/kg in cynomolgus monkeys.\nConclusions: DB-1323 overcomes historical MSLN-targeting liabilities through unique rapid-on/off binding, efficient internalization, and potent topoisomerase I inhibition, delivering superior tumor eradication versus at well-tolerated doses. These data support clinical evaluation of DB-1323 for patients with MSLN expressing tumors.", "source_company": "Duality Biologics Ltd", "source_org_type": "公司", "row_number": 231, "target_meta": "MSLN", "MOA_meta": "抗体偶联药物"}, {"drug_name": "EGFR×FGFR2b bispecific ADC", "company": "Earendil Labs", "org_type": "公司", "target": "EGFR, FGFR2b", "modality": "bispecific ADC", "importance_level": "高", "total_score": 77.8, "institution_score": 85, "track_score": 92, "milestone_score": 45, "field_heat_score": 85, "bonus_score": 3, "brief_reason": "靶向EGFR和FGFR2b的双特异性ADC，针对胃癌中共同过表达的靶点，设计为部分阻断FGFR2b配体以潜在降低毒性，采用AI驱动的头部biotech公司开发。机构为近期获巨额融资并与Sanofi等合作的前沿AI-biotech，得分高；赛道为热门bispecific ADC+胃癌高未满足需求靶点，preclinical阶段但有体外体内数据支持。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9673", "id": "bZ7M_5wBZznHJdnt_W3O", "source_drug_name": "EGFR×FGFR2b bispecific ADC", "title": "Engineering and development of a novel bispecific ADC targeting EGFR and FGFR2b", "abstract_text": "EGFR is a clinically validated oncogenic driver frequently overexpressed in gastric cancer. Fibroblast growth factor receptor 2b (FGFR2b), a transmembrane receptor tyrosine kinase,is likewise overexpressed in approximately 30% of gastric and gastroesophageal junction (GEJ) cancers, and is associated with poor prognosis. Notably, subsets of gastric tumors co‑express EGFR and FGFR2b, indicating potential cooperative signaling that contributes to tumor progression and therapeutic resistance. Bemarituzumab, an afucosylated FGFR2b monoclonal antibody has shown efficacy in the clinical study for the treatment in patients with FGFR2b‑positive GC and GEJ cancer. However, the clinical application of bemarituzumab is accompanied by safety concerns. The corneal adverse events were frequently observed. Co-expression of EGFR and FGFR2b presents an attractive opportunity for a dual targeting strategy and supports the bispecific design that could potentially address the safety issues. In this study, we developed several bispecific antibodies (bsAb) targeting EGFR and FGFR2b. These bsAb demonstrated enhanced binding avidity and superior internalization efficiency compared with bemarituzumab and BG‑C137 mAb analogs in EGFR⁺/FGFR2b⁺ dual expressing cancer cell lines. Our EGFR×FGFR2b bsAb function as a partial FGFR2b ligand blocker, and only weakly inhibiting FGF7 while sparing FGF10‑mediated signaling, thus with the potential to reduce on‑target toxicity associated with FGF7/FGF10 blockade. Several bsAb ADC were generated with various cytotoxic payloads and are being tested in vitro and in vivo studies.", "source_company": "Earendil Labs.", "source_org_type": "公司", "row_number": 1023, "target_meta": "EGFR,FGFR2", "MOA_meta": "抗体偶联药物"}, {"drug_name": "NW008", "company": "Chengdu Chipscreen Newway Biosciences Co., Ltd.", "org_type": "公司", "target": "MICA/B", "modality": "ADC", "importance_level": "高", "total_score": 77.5, "institution_score": 75, "track_score": 85, "milestone_score": 70, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "NW008为首创双功能anti-MICA/B ADC，通过抑制MICA/B脱落恢复NKG2D介导的抗肿瘤免疫并直接递送拓扑异构酶I抑制剂杀伤肿瘤细胞。机构为国内知名创新药企Chipscreen旗下专注于大分子/ADC的子公司，ADC赛道热门且MICA/B为肿瘤广谱新兴靶点，前临床数据强劲（多模型TGI>85%），综合潜力较高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5483", "id": "wJ7M_5wBZznHJdnt_W3O", "source_drug_name": "NW008", "title": "Preclinical study of NW008, a novel dual-functional anti-MICA/B antibody-drug conjugate", "abstract_text": "Background: The MHC class I polypeptide-related sequences A and B (MICA and MICB; collectively MICA/B) are stress-induced antigens. They are minimally expressed in healthy tissues but overexpressed in a wide range of solid tumors. Membrane-bound MICA/B activates antitumor immunity by engaging the NKG2D receptor on immune effector cells, such as CD8-positive T cells, natural killer (NK) cells and γδ T cells. However, proteases in the tumor microenvironment (TME) cleave MICA/B from the tumor cell surface, which impairs NKG2D-mediated tumor recognition and facilitates immune evasion. Furthermore, soluble MICA/B induces sustained NKG2D activation, resulting in receptor downregulation and lymphocyte dysfunction. Elevated serum levels of soluble MICA are associated with poor patient survival, highlighting the therapeutic potential of targeting MICA/B.\nMethods: Mice were immunized with recombinant proteins containing the α3 domain derived from multiple MICA/B alleles. A humanized anti-MICA/B antibody that binds with high affinity to various MICA/B alleles was obtained through high-throughput screening. Each antibody molecule was site-specifically conjugated to four molecules of a highly potent topoisomerase I inhibitor via a specially designed, hydrophilic, enzyme-cleavable linker that suppresses the retro-Michael reaction, resulting in the ADC candidate NW008. The in vitro antitumor activity of NW008 was evaluated using multiple MICA/B-expressing tumor cell lines. Its in vivo efficacy was assessed in several cell-derived xenograft (CDX) models.\nResults: The humanized anti-MICA/B antibody exhibited high internalization efficiency and sub-nanomolar affinity for multiple MICA/B alleles. It also inhibited MICA/B shedding from tumor cells and enhanced MICA/B-NKG2D interactions. The ADC molecule NW008 demonstrated high homogeneity and favorable stability, and it showed potent cytotoxicity against a variety of MICA/B-expressing tumor cell lines, with half-maximal effective concentration (EC₅₀) values in the nanomolar range. In multiple mouse xenograft models bearing human MICA/B-expressing tumors, NW008 exhibited significant antitumor efficacy in vivo, with maximum tumor growth inhibition (TGI) exceeding 85% in all models, and was well tolerated.\nConclusion: MICA/B represents a highly attractive target for ADC development. NW008 is a first-in-class dual-functional ADC that acts by restoring antitumor immunity through inhibition of MICA/B shedding and directly eliminating tumor cells via targeted delivery of a topoisomerase I inhibitor. NW008 demonstrates robust antitumor efficacy in preclinical models, supporting its clinical development as a promising therapeutic candidate for MICA/B‑positive solid tumors.", "source_company": "Chengdu Chipscreen Newway Biosciences Co., Ltd.", "source_org_type": "公司", "row_number": 116, "target_meta": "MICA/B", "MOA_meta": "抗体偶联药物"}, {"drug_name": "OncoFAP-GlyPro-MB357", "company": "Philochem AG", "org_type": "公司", "target": "FAP", "modality": "other", "importance_level": "高", "total_score": 77.5, "institution_score": 75, "track_score": 85, "milestone_score": 70, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "该药为靶向FAP的小分子-免疫刺激物偶联物（SMIC），搭载新型TLR7激动剂MB357，利用GlyPro连接子实现肿瘤特异性释放，展现完全肿瘤清除和长期免疫保护的强效preclinical数据。机构为Philogen集团旗下专注小分子配体的瑞士biotech，已有OncoFAP平台多个项目进入临床并获BMS高价授权，赛道结合热门FAP靶点与TLR激动剂肿瘤局部激活机制具创新性与较高潜力，故综合评分较高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5579", "id": "Tp7M_5wBZznHJdnt_W3O", "source_drug_name": "OncoFAP-GlyPro-MB357", "title": "FAP-targeting Small molecule-immunostimulator conjugate bearing a novel TLR7 agonist payload induces tumor eradication and long-lasting antitumor immunity in vivo", "abstract_text": "While antibody-based immune checkpoint inhibitors have shown remarkable success in cancer therapy, their efficacy is often limited by poor T-cell infiltration in many tumors. Activation of pattern recognition receptors such as toll-like receptors (TLRs) can trigger cytokine production and amplify antitumor immune responses. However, systemic administration of TLR agonists frequently induces severe adverse effects through uncontrolled immune activation. To overcome this issue, targeting approaches such as immunostimulating antibody conjugates (ISACs) have been developed to selectively deliver the payload to the tumor, thereby potentiating efficacy and reducing systemic toxicities. The replacement of the tumor-homing antibody with a small molecule possessing a high affinity towards a tumor-associated antigen affords small molecule-immunostimulator conjugates (SMICs), offering several advantages, including a more rapid extravasation, an efficient tissue penetration, leading to a homogeneous and selective uptake within antigen-positive tumor masses. In this work, we developed a SMIC bearing the OncoFAP moiety targeting Fibroblast Activation Protein (FAP), an endopeptidase abundant in the stroma of most solid tumors, and featuring a novel proprietary TLR agonist as a payload. Through a screening of different TLR1/2 and TLR7 agonists, we identified MB357, a novel potent TLR7 agonist with a single-digit nanomolar activity in vitro. To enhance tumor specificity and improve tumor exposure to the drug, we employed the FAP-cleavable Glycine-Proline linker, which rapidly and selectively releases high concentrations of the active TLR agonist to the FAP-positive lesions. The SMIC was tested for its activity on immunocompetent mice bearing FAP positive tumors, showing complete tumor eradication in all treated animals and long-lasting antitumor immunity, without any sign of toxicity. The promising preclinical results provided the rationale to start a clinical trial to investigate the safety and efficacy of OncoFAP-GlyPro-MB357 in canine patients with spontaneous solid tumors.", "source_company": "Philochem AG", "source_org_type": "公司", "row_number": 123, "target_meta": "FAP", "MOA_meta": "其他"}, {"drug_name": "BSI-737", "company": "Biosion Inc.", "org_type": "公司", "target": "B7-H3 × PD-L1", "modality": "bispecific ADC", "importance_level": "高", "total_score": 77.5, "institution_score": 65, "track_score": 90, "milestone_score": 75, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "BSI-737为B7-H3×PD-L1双特异性ADC，结合双靶点阻断免疫检查点并通过exatecan介导的细胞毒作用增强抗肿瘤免疫反应。Biosion作为国内临床阶段biotech，赛道热门（双抗ADC+B7-H3/PD-L1高热度），preclinical展示优异疗效及完全肿瘤消退，IND-enabling研究进行中，综合潜力较高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4320", "id": "9VXM_5wBX1NQZOEH-LO6", "source_drug_name": "BSI-737", "title": "BSI-737, a best-in-class B7H3xPD-L1 bi-specific ADC with dual function to eliminate tumor via selective killing and exacerbated anti-tumor immune response", "abstract_text": "Background: B7H3 and PD-L1 are both inhibitory immune checkpoints. The dual targeting of B7H3 and PD-L1, which are prevalently co-expressed in various malignancies, may synergistically enhance anti-tumor immune response. PD-L1-directed ADCs have shown modest efficacy with no target-related safety issues. B7-H3, by comparison, is a clinically validated ADC target that tolerates high-dose exposure without target-mediated toxicity and supports added immune-checkpoint blockade. B7H3xPD-L1 bi-specific ADC may hold promise via bi-specific binding mode, cytotoxic agent-mediated immunogenic cell death, and exacerbated anti-tumor immune response.\nMethods: The B7H3xPD-L1 bi-specific antibody was composed of humanized anti-PD-L1 and anti-B7H3 antibodies identified from A/J mice immunized with PD-L1-ECD-Fc and HG5042 mice immunized with B7H3-EDC-Fc, respectively. The final bi-specific construct was selected based on simultaneous binding to B7H3 and PD-L1, efficient cell internalization, and strong PD-1/PD-L1 signal blocking. The bi-specific antibody was conjugated to exatecan via a glycol-site-specific conjugation technology in a DAR of 4. The anti-tumor activity of BSI-737 was investigated in cell-derived xenograft models with various expression levels of B7H3 and PD-L1. The CMC developability as well as the stability of BSI-737 in mouse and human plasma were also assessed.\nResults: BSI-737 simultaneously bound to B7H3 and PD-L1 with high affinity and showed strong PD-1/PD-L1 signal blocking activity. The binding of BSI-737 resulted in efficient antibody-induced internalization across cell lines expressing various levels of B7H3 and PD-L1. When conjugated to exatecan via a cleavable linker in DAR of 4, BSI-737 demonstrated an outstanding anti-tumor activity compared to clinical benchmarks. A single administration of BSI-737 resulted in a complete tumor regression in a CDX model expressing high level of B7H3 with a survival rate of 100% by the end of the study. A significant anti-tumor activity of BSI-737 after a single administration was also observed in a B7H3-medium expressing model. BSI-737 possessed a favorable CMC developability profile.\nConclusion: BSI-737 is a B7-H3 × PD-L1 bispecific ADC with best-in-class potential, leveraging dual targeting to enable selective tumor cell killing while amplifying anti-tumor immune responses. The current pre-clinical data highlight the potential of BSI-737 across expression levels of B7H3 and further pharmacokinetics, toxicity, and IND-enabling studies are underway.", "source_company": "Biosion Inc.", "source_org_type": "公司", "row_number": 131, "target_meta": "CD276,PDL1", "MOA_meta": "抗体偶联药物"}, {"drug_name": "QLS1403", "company": "Shanghai Qilu Pharmaceutical Research and Development Center LTD.", "org_type": "公司", "target": "PARG", "modality": "inhibitor", "importance_level": "高", "total_score": 77.5, "institution_score": 75, "track_score": 85, "milestone_score": 70, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "QLS1403为新型PARG抑制剂，针对HRD癌症尤其是PARPi耐药模型显示优于IDE-161的体外/体内活性。齐鲁制药作为国内TOP pharma，PARG作为新兴DNA修复靶点赛道热度高，preclinical数据强劲，支持临床推进。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8861", "id": "VlXM_5wBX1NQZOEH-LO6", "source_drug_name": "QLS1403", "title": "QLS1403, a novel and potent PARG inhibitor with robust anti-tumor efficacy in homologous recombination deficient cancer models", "abstract_text": "Background: Cancer cells experience high levels of endogenous replication stress due to persistent proliferative signaling. Poly (ADP-ribose) polymerase (PARP) is a first responder to DNA damage, catalyzing the synthesis of poly (ADP-ribose) (PAR) chains that serve as docking platforms for DNA repair proteins. The hydrolysis of these PAR chains, a critical step for the turnover of repair complexes, is primarily mediated by poly (ADP-ribose) glycohydrolase (PARG). Pharmacological inhibition or genetic loss of PARG prevents PAR chain hydrolysis, which results in persistent stalling of replication fork, nucleolytic degradation of nascent and parental DNA and ultimately cell death. IDE-161, a first-in-class PARG inhibitor has entered clinical trials. This study reports the discovery and characterization of QLS1403, a proprietary PARG inhibitor designed to selectively treat homologous recombination deficient (HRD) cancers, particularly those resistant to PARP inhibitors (PARPi) or T-Dxd.\nExperimental Procedures: The activities of QLS1403 were characterized by biochemical PARG inhibition assay, cellular viability assessment in HRD-positive and PARPi-resistant or T-Dxd-resistant cancer cell lines and in vivo evaluation of efficacy in ovarian and breast cancer xenograft models. In addition, the pharmacodynamic effect, i.e., the PAR chain accumulation and its pharmacokinetic properties were assessed in both cells and animals.\nResults: QLS1403 demonstrated exceptional PARG inhibitory activity (IC₅₀ = 0.35 nM) and remarkable cellular activity in HRD-positive cancer cell lines, showing approximately 10-fold greater potency than IDE-161. Notably, QLS1403 showed strong activity in PARPi- or T-Dxd-resistant cell lines. Also, QLS1403 caused tumor regression at lower doses across multiple xenograft models with intrinsic PARPi resistance, accompanied by dose-dependent PAR accumulation in tumors. In addition, QLS1403 exhibited a clean selectivity and safety profile in vitro, with no significant off-target activity observed in safety assessment panels.\nConclusion: QLS1403 demonstrates superior potency, sustained efficacy in PARPi-resistant and T-Dxd-resistant cancer cell lines, while displaying favorable safety. These compelling data support its clinical evaluation as a new therapeutics for patients with HRD-positive cancers with acquisition of resistance to PARPi or potentially other existing treatments, such as T-Dxd.", "source_company": "Shanghai Qilu Pharmaceutical Research and Development Center LTD.", "source_org_type": "公司", "row_number": 136, "target_meta": "PARG", "MOA_meta": "抑制剂"}, {"drug_name": "ALX007", "company": "Shanghai Ailux Biotechnology Co., Ltd.", "org_type": "公司", "target": "FGFR2b", "modality": "ADC", "importance_level": "高", "total_score": 77.5, "institution_score": 75, "track_score": 85, "milestone_score": 70, "field_heat_score": 80, "bonus_score": 8, "brief_reason": "ALX007为新型非配体阻断表位的FGFR2b靶向ADC，显著降低眼毒性风险，在异种移植模型中显示优于Bemarituzumab的抗肿瘤疗效。公司为XtalPi旗下AI驱动生物技术创新平台，已与Lilly等头部药企合作。ADC+新兴靶点FGFR2b（胃癌30%表达）赛道热度高，前临床数据扎实具差异化亮点。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4482", "id": "4FXM_5wBX1NQZOEH-LC5", "source_drug_name": "ALX007", "title": "Preclinical evaluation of a novel and highly differentiated FGFR2b-targeting ADC with low risk of ocular toxicity", "abstract_text": "Background: Fibroblast growth factor receptor-2 isoform IIIb (FGFR2b) plays a crucial role in the tumorigenesis and disease progression of several solid tumors, its overexpression is associated with poor prognosis. About 30% of gastric and gastroesophageal junction (G/GEJ) adenocarcinomas express FGFR2b with limited overlap with current biomarkers, this makes FGFR2b an attractive target. Bemarituzumab, an ADCC-enhanced FGFR2b antagonist, has demonstrated efficacy in patients with FGFR2b-overexpressing G/GEJ cancer. However, its therapeutic benefit appears to be limited by corneal adverse events, likely resulting from the strong blockade of FGFR2b ligands FGF7 and FGF10. Here we developed a novel FGFR2b-targeting ADC based on a highly differentiated antibody, ALX007, which completely spares ligand-receptor interaction and showed an encouraging ocular safety profile in preclinical models.\nMethods: Hit antibodies were generated by hybridoma, triaged using a proprietary structural modeling algorithm, and humanized. Antibody binding and internalization were evaluated, and blockade of FGF7 and FGF10 binding to FGFR2b-overexpressing cells was analyzed by flow cytometry. The lead antibody was conjugated to a topoisomerase I inhibitor via a stable and enzyme cleavable linker. Anti-tumor efficacy of the resulting ADC was assessed using FGFR2b-positive xenograft mouse models. PK profile and ocular toxicity were evaluated in relevant mouse models.\nResults: The naked antibody ALX007 demonstrated selective, high-affinity FGFR2b binding and rapid internalization in cell lines with varying levels of FGFR2b protein expression. Importantly, ALX007 did not inhibit the interaction between FGF7/FGF10 and FGFR2b even at high concentrations, distinguishing it from Bemarituzumab and several other reference antibodies with potent ligand blockade (IC50 < 5 nM). Both structural modeling and epitope binning experiments revealed that ALX007 recognizes a novel, non-ligand-blocking epitope. Functional studies further confirmed that ALX007 did not inhibit FGF7/FGF10-induced FGFR2b phosphorylation. In the SNU-16 gastric cancer xenograft model, a single dose of the FGFR2b-targeting ADC showed sustained and superior anti-tumor efficacy compared with repeated doses of Bemarituzumab. Both the ALX007 naked antibody and its ADC exhibited significantly lower corneal dystrophy than Bemarituzumab in mice. In a human FcRn transgenic mouse model, no apparent difference in serum concentrations was observed between conjugated and total antibodies, indicating a stable antibody-linker conjugation.\nConclusion: Together, these data demonstrate preclinical efficacy and low risk of ocular toxicity of a FGFR2-targeting ADC utilizing ALX007 as a highly differentiated antibody backbone. Further development for the treatment of FGFR2b-expressing tumors is warranted.", "source_company": "Shanghai Ailux Biotechnology Co., Ltd.", "source_org_type": "公司", "row_number": 149, "target_meta": "FGFR2", "MOA_meta": "抗体偶联药物"}, {"drug_name": "QLS1522", "company": "Shanghai Qilu Pharmaceutical Research and Development Center LTD.", "org_type": "公司", "target": "PI3Kα (mutant-selective)", "modality": "inhibitor", "importance_level": "高", "total_score": 77.5, "institution_score": 85, "track_score": 80, "milestone_score": 65, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "QLS1522为突变选择性变构PI3Kα抑制剂，针对PIK3CA突变实体瘤，具有改善治疗窗和降低血糖代谢毒性的潜力；齐鲁制药作为国内TOP pharma（多次跻身中国制药企业前3-5名），赛道热门（mutant-selective PI3Kα抑制剂竞争激烈但前景好），IND-enabling阶段并显示优于竞品数据，故综合评分较高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8779", "id": "KVXM_5wBX1NQZOEH-LG5", "source_drug_name": "QLS1522", "title": "Discovery of QLS1522, a mutant-selective allosteric PI3Kα inhibitor for the treatment of PIK3CA-mutant solid tumors", "abstract_text": "Background: PIK3CA is a predominant oncogene in human cancers. While approved PI3Kα inhibitors like Alpelisib validate that PI3Kα blockade can suppress tumors and improve outcomes in PIK3CA-mutant ER+HER2- breast cancer, their major on-target toxicity against wild-type PI3Kα interferes with regulation of glucose metabolism which reduces their therapeutic index and limits clinical efficacy. Development of PIK3CA mutant selective inhibitors can significantly improve therapeutic window and anti-tumor efficacy by substantially reducing side effects.\nExperimental procedures: The enzymatic activity was evaluated in biochemical and biophysical assays. Viability of cell lines was measured using CellTiterGlo®. Antitumor activity was evaluated in ER+ breast cancer cell line-derived xenograft (CDX) models with either kinase domain or helical domain mutations. The impact on glucose metabolism was analyzed using an oral glucose tolerance test (OGTT).\nResults: QLS1522 is a potent, selective allosteric PI3Kα inhibitor designed to spare wild-type PI3Kα. It exhibited nanomolar potency against the PIK3CA H1047R mutation with high selectivity over wild-type PI3Kα and other isoforms (β, γ, δ). In a 447-kinase selectivity panel, QLS1522 showed outstanding specificity, with only Aurora-B kinase exhibiting >50% inhibition at 10 µM (IC₅₀ of 7.8 µM for QLS1522 vs. 1.4 µM for STX-478). Cell panel studies revealed that QLS1522 exerted broad inhibitory effects across cancer cell lines carrying either kinase domain or helical domain mutations. In comparative analyses with other clinical-stage candidates such as STX-478 and RLY-2608, QLS1522 showed enhanced inhibition of pAKT in the T47D breast cancer cell line harboring the PIK3CA H1047R mutation. Notably, it maintained selectivity comparable to STX-478 and better than RLY-2608 in wild-type SKBR3 cells. In vivo, QLS1522 was well tolerated and exhibited potent antitumor efficacy in multiple ER+ breast cancer CDX models, without inducing significant glucose metabolism abnormalities. The combination of QLS1522 with standard-of-care (SoC) agents resulted in enhanced efficacy compared to monotherapy or SoC alone. QLS1522 demonstrated a favorable drug-like profile, characterized by superior solubility, permeability, and excellent pharmacokinetic properties across species, with a wide therapeutic window.\nConclusions: QLS1522 is a mutant-selective allosteric PI3Ka inhibitor and represents a promising therapeutic candidate for treating PIK3CA-mutant solid tumors. IND-enabling studies are currently in progress.", "source_company": "Shanghai Qilu Pharmaceutical Research and Development Center LTD.", "source_org_type": "公司", "row_number": 176, "target_meta": "PI3Kα", "MOA_meta": "抑制剂"}, {"drug_name": "QLS1303", "company": "Shanghai Qilu Pharmaceutical Research and Development Center LTD.", "org_type": "公司", "target": "KIF18A", "modality": "inhibitor", "importance_level": "高", "total_score": 77.5, "institution_score": 75, "track_score": 85, "milestone_score": 70, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "QLS1303为口服生物利用度高的KIF18A抑制剂，靶向CIN高肿瘤的合成致死机制，展示出强效选择性抗肿瘤活性及良好安全性，支持进入临床。齐鲁制药作为国内头部药企，KIF18A赛道在2026年热度高企（多款抑制剂已临床阶段），preclinical数据强劲但仍处早期。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8857", "id": "KVXM_5wBX1NQZOEH-LK6", "source_drug_name": "QLS1303", "title": "Discovery of QLS1303, a potent and selective KIF18A inhibitor with robust anti-tumor activity in CIN+ preclinical cancer models", "abstract_text": "Background: Chromosomal instability (CIN) underlies the aneuploidy present in ~90 % of solid tumors and engenders a persistent requirement for the plus-end kinesin KIF18A to silence mitotic checkpoints and align extra chromosomes. Consequently, KIF18A inhibition triggers catastrophic mis-segregation exclusively in CIN-high cells, inducing mitotic arrest or apoptosis, while sparing normal diploid cells. This synthetic-lethal interaction makes KIF18A as an attractive, cancer-selective therapeutic target, which prompted multiple drug-discovery programs, including AMG 650, a clinical-stage KIF18A inhibitor. Here we report the discovery and preclinical profiling of QLS1303, a novel, potent and orally bioavailable KIF18A inhibitor engineered to against aneuploid cancers with CIN-specific vulnerability.\nExperimental Procedures: The inhibitory activity of QLS1303 was assessed through biochemical (KIF18A motor activity) and cellular proliferation assays using CIN+ and near-diploid cancer cell lines. In vivo efficacy and tolerability were evaluated in TP53mut/aneuploidy-high CDX models following once-daily oral administration. Selectivity and safety were profiled against a panel of 46 safety targets.\nResults: QLS1303 potently inhibited KIF18A motor activity (IC₅₀ = 13 nM) with a good selectivity over known toxic kinesin family members. It selectively suppressed proliferation of CIN+ cell lines (IC₅₀ = 4-14 nM) with minimal effects on near-diploid cells. Once-daily oral administration of QLS1303 at 3 and 10 mg/kg was well-tolerated and induced tumor regression in multiple TP53mut/aneuploidy-high CDX models, and achieved tumor stasis at one-tenth of AMG 650 dosage in OVCAR3 xenograft model. A clean selectivity and safety profile were confirmed with no significant inhibition (IC₅₀ > 10 µM) across the 46-target panel. In addition, QLS1303 exhibits favorable drug-like properties and a promising predicted therapeutic window.\nConclusion: QLS1303 is a highly potent, selective, and orally bioavailable KIF18A inhibitor, demonstrating robust anti-tumor activity in CIN+ preclinical models and a compelling safety profile. These data strongly support its advancement into clinical studies.", "source_company": "Shanghai Qilu Pharmaceutical Research and Development Center LTD.", "source_org_type": "公司", "row_number": 210, "target_meta": "KIF18A", "MOA_meta": "抑制剂"}, {"drug_name": "BCG037", "company": "Biocytogen", "org_type": "公司", "target": "ALPP/ALPG", "modality": "ADC", "importance_level": "高", "total_score": 77.5, "institution_score": 75, "track_score": 80, "milestone_score": 75, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "BCG037为靶向ALPP/ALPG的first-in-class ADC，Biocytogen作为国内头部biotech平台型公司具有较强抗体和模型技术基础；赛道ADC热门且靶点为新型oncofetal抗原，具有高特异性和临床潜力，PDX模型中优于benchmark SGN-ALPV-MMAE。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5440", "id": "BFXM_5wBX1NQZOEH-LO6", "source_drug_name": "BCG037", "title": "BCG037, a first-in-class anti-human ALPP/ALPG therapeutic ADC that inhibits tumor growth in pancreatic cancer and gastric cancer PDX models", "abstract_text": "Placental (ALPP) and germ cell (ALPG) alkaline phosphatases, sharing 98% sequence homology, are tumor-associated antigens with a highly restricted expression profile. While largely absent in normal adult tissues, they are frequently overexpressed across a wide spectrum of malignancies, including pancreatic, gastric, ovarian, and lung cancers. Elevated ALPP/ALPG levels correlate with poor prognosis in gastric and ovarian cancers, making them compelling targets for antibody-based therapies. Here, we report the development of BCG037, a first-in-class, fully human IgG1 antibody-drug conjugate (ADC) targeting ALPP/ALPG. The antibody was generated from RenMab™ humanized mice and conjugated with the potent topoisomerase I (Top1) inhibitor payload, achieving a high drug-to-antibody ratio (DAR) of ~8. BCG037 exhibits high affinity (nanomolar range) and cross-reactivity to both human and cynomolgus monkey ALPP/ALPG, with no cross-reactivity to other ALP family members (ALPL, ALPI). Notably, the antibody component of BCG037 demonstrates superior binding affinity to tumor cells compared to the analog used in SGN-ALPV. In vivo, BCG037 treatment led to significant and superior tumor growth inhibition in both pancreatic and gastric cancer patient-derived xenograft (PDX) models, outperforming the benchmark ADC, SGN-ALPV-MMAE, and no treatment-related toxicity or weight loss was observed in mice. Collectively, these data validate ALPP/ALPG as promising therapeutic targets and position BCG037 as a highly novel and potent clinical candidate for treating ALPP/ALPG-positive malignancies, including refractory cancers with limited treatment options.", "source_company": "Biocytogen", "source_org_type": "公司", "row_number": 229, "target_meta": "ALPP,ALPG", "MOA_meta": "抗体偶联药物"}, {"drug_name": "BCG044", "company": "Biocytogen", "org_type": "公司", "target": "EpCAM 和 HER3", "modality": "bispecific ADC", "importance_level": "高", "total_score": 77.5, "institution_score": 75, "track_score": 85, "milestone_score": 70, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "BCG044为Biocytogen开发的EpCAM×HER3双特异性ADC，采用1+1格式结合新型TOP1抑制剂payload，在PDX模型中显示优于单靶点基准ADC的疗效，并通过人源化小鼠模型验证降低毒性。机构为国内知名抗体技术平台公司，赛道为热门双特异ADC+热门靶点，preclinical数据较扎实且有毒性改善亮点。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4469", "id": "M1XM_5wBX1NQZOEH-LO6", "source_drug_name": "BCG044", "title": "Preclinical study of BCG044, a novel bispecific ADC targeting EpCAM and HER3 for the treatment of colorectal and other tumors", "abstract_text": "Colorectal cancer (CRC) is the third most common cancer and the second leading cause of cancer-related deaths. Unfortunately, current therapies have limited effectiveness on long-term survival. Antibody-drug conjugates (ADCs) represent an emerging class of treatments with potential in oncology, but their efficacy in colorectal cancer has been limited thus far. Therefore, identifying new drug targets and developing ADCs are essential for improving treatment outcomes. Epithelial cell adhesion molecule (EpCAM) is a transmembrane glycoprotein widely expressed in various cancers, notably colorectal, gastric, ovarian, and lung cancers. However, its presence in normal tissues has led to adverse effects from previous biologic therapies, including gastrointestinal toxicity and pancreatitis associated with systemic administration.\nIn this study, we developed an innovative approach to generate a bispecific ADC targeting both EpCAM and HER3, another antigen that is widely overexpressed in various solid tumors, including gastrointestinal cancers, breast cancer, and NSCLC. By employing a \"1+1\" format, we aimed to mitigate EpCAM-related toxicity while enhancing tumor selectivity. The BCG044 bispecific antibody (bsAb) effectively bound to a diverse range of gastrointestinal tumor cell lines. Notably, the monovalent form of EpCAM and HER3 resulted in decreased internalization within tumor cells. In contrast, simultaneous engagement of both targets by bsAbs maximized internalization. This suggests that bsAb requires targeting of tumor cells with bivalency. When conjugated with BLD1102, a novel TOP1 inhibitor linker-payload, BCG044 exhibited potent efficacy comparable to the EpCAM benchmark ADC and demonstrated stronger effects than the HER3 benchmark ADC in colorectal, breast, and NSCLC PDX models. Subsequently, we utilized humanized EpCAM mice to test a surrogate ADC that contained the same EpCAM arm, along with a HER3 arm that cross-reacted with mouse HER3. The surrogate ADC demonstrated better tolerance compared to both the parent EpCAM ADC. In summary, BCG044 exhibited the potential to enhance tumor selectivity while maintaining potent efficacy against colorectal and other solid tumors.", "source_company": "Biocytogen", "source_org_type": "公司", "row_number": 233, "target_meta": "EpCAM,HER3", "MOA_meta": "抗体偶联药物"}, {"drug_name": "²²⁵Ac-RAX104", "company": "RadAlliance Therapeutics Inc", "org_type": "公司", "target": "PSMA", "modality": "RLT imaging agent", "importance_level": "高", "total_score": 77.5, "institution_score": 65, "track_score": 90, "milestone_score": 75, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "靶向PSMA的²²⁵Ac-α粒子放射性配体药物，优化亲和力和肿瘤滞留，显著优于对照²²⁵Ac-PSMA-617。机构为新成立临床阶段放射性药物biotech，赛道为热门α-RLT+PSMA，preclinical数据强劲且已提出IIT，综合潜力较高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3895", "id": "UVXM_5wBX1NQZOEH-LO6", "source_drug_name": "²²⁵Ac-RAX104", "title": "²²⁵Ac-RAX104: A novel PSMA-targeted radioligand optimized for actinium-225 demonstrates enhanced tumor retention and superior efficacy", "abstract_text": "Prostate cancer is the second most common malignancy in men and remains a significant cause of cancer-related mortality worldwide. Although the clinical success of ¹⁷⁷Lu-PSMA-617 (Pluvicto) has established PSMA-targeted radioligand therapy (RLT) as an effective treatment for metastatic castration-resistant prostate cancer (mCRPC), emerging clinical evidence indicates that ²²⁵Ac-based RLT can deliver even greater therapeutic efficacy owing to the high linear energy transfer of α-particles and the radionuclide’s 9.92-day physical half-life. To fully exploit these properties, ²²⁵Ac-RAX104 was rationally designed to enhance PSMA affinity and tumor retention, thereby kinetically matching the physical and radiobiological characteristics of ²²⁵Ac to maximize antitumor potency. RAX104 was successfully synthesized and radiolabeled with ²²⁵Ac at a molar activity of up to 3 µCi/nmol, achieving radiochemical purity greater than 95% and maintaining stability for more than 110 hours. Surface plasmon resonance analysis revealed that the RAX104 precursor exhibited approximately 22-fold higher affinity for PSMA than PSMA-617, primarily driven by slower dissociation kinetics. In PSMA-overexpressing PC3 cells, ²²⁵Ac-RAX104 showed markedly enhanced cellular uptake and internalization compared with ²²⁵Ac-PSMA-617. In PSMA-low 22Rv1 xenografts, ²²⁵Ac-RAX104 achieved more than 3-fold higher tumor-absorbed activity (AUC₀₋∞) and a significantly prolonged biological half-life in tumors relative to ²²⁵Ac-PSMA-617, while both radioligands showed comparable blood pharmacokinetics. Consistent with these pharmacokinetic advantages, ²²⁵Ac-RAX104 demonstrated superior antitumor efficacy: a single 14.8 kBq dose produced greater tumor growth inhibition and longer survival than 74 kBq (fivefold higher activity) of ²²⁵Ac-PSMA-617 in the 22Rv1 model. Toxicity evaluation in normal ICR mice revealed only transient and reversible reductions in white blood cell, neutrophil, and reticulocyte counts, without clinical chemistry abnormalities, indicating a favorable safety profile. An investigator-initiated trial (IIT) of ²²⁵Ac-RAX104 has been proposed in mCRPC patients to generate human dosimetry data to inform the design of subsequent clinical studies. Collectively, these results demonstrate that ²²⁵Ac-RAX104 achieves optimal kinetic alignment with ²²⁵Ac’s physical decay and biological action, delivering enhanced tumor exposure and potent therapeutic efficacy at one-fifth the dose of ²²⁵Ac-PSMA-617. These findings support ²²⁵Ac-RAX104 as a promising next-generation PSMA α-radioligand therapy with the potential to improve outcomes in mCRPC and warrant further clinical development.", "source_company": "RadAlliance Therapeutics Inc", "source_org_type": "公司", "row_number": 236, "target_meta": "PSMA", "MOA_meta": "其他"}, {"drug_name": "CKD-9001", "company": "CKD Pharmaceutical Corp.", "org_type": "公司", "target": "PARP1", "modality": "inhibitor", "importance_level": "高", "total_score": 77.5, "institution_score": 75, "track_score": 85, "milestone_score": 70, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "CKD-9001为新型PARP1选择性抑制剂兼DNA trapper，针对HRD癌症，相较pan-PARP抑制剂显著提升疗效并降低血液毒性，还可穿透BBB。CKD作为韩国老牌TOP pharma之一，研发实力较强，此preclinical数据突出安全性与脑渗透优势，赛道热门且有差异化亮点。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8824", "id": "FFXM_5wBX1NQZOEH-LS6", "source_drug_name": "CKD-9001", "title": "Discovery and characterization of CKD-9001, a novel PARP1-selective inhibitor and DNA trapper with enhanced efficacy and an improved toxicity profile in HRD cancers", "abstract_text": "Poly(ADP-ribose) polymerase (PARP) inhibitors have been established as therapeutic agents for patients with homologous recombination repair (HRR) deficiencies, such as BRCA1/2 mutations, in ovarian, breast, prostate, and pancreatic cancers. Currently, pan-PARP inhibitors that have received approval target both PARP1 and PARP2, demonstrating potent antitumor activity. However, PARP2 inhibition has been identified as a major contributor to hematologic toxicity, resulting in dose limitations and treatment discontinuation. Given PARP1’s role as the primary enzyme in sensing single-strand breaks and regulating DNA repair processes, the development of PARP1-selective inhibitors has emerged as a promising strategy to achieve potent antitumor efficacy while minimizing toxicity compared with conventional pan-PARP inhibitors. In this study, we present the preclinical development of CKD-9001, a novel PARP1-selective inhibitor and potent DNA trapper.We developed CKD-9001, a next-generation PARP1-selective inhibitor, and evaluated its preclinical efficacy and toxicity profile against the leading agents, olaparib and saruparib. Our findings demonstrated excellent selectivity for PARP1, as evidenced by its high levels of enzymatic inhibition and DNA-trapping potency.In vitro studies demonstrated that CKD-9001 exhibited potent antiproliferative effects, with IC50 values ≤10 nM in HRR-deficient and BRCA2-knockout cancer cell lines. In vivo studies showed remarkable antitumor efficacy of CKD-9001, even at low doses, in HRR-deficient animal models. Furthermore, pharmacokinetic and safety analyses confirmed that CKD-9001 markedly reduced hematologic toxicity and significantly improved the safety margin compared with conventional pan-PARP inhibitors. In addition, we found that CKD-9001 was capable of penetrating the blood-brain barrier (BBB).In conclusion, CKD-9001 is a next-generation PARP1-selective inhibitor that successfully combines enhanced efficacy with remarkably low toxicity, demonstrating outstanding therapeutic potential in HRD cancers.", "source_company": "CKD Pharmaceutical Corp.", "source_org_type": "公司", "row_number": 250, "target_meta": "PARP1", "MOA_meta": "抑制剂"}, {"drug_name": "CD3+CD7 bispecific antibody", "company": "Probio Inc", "org_type": "公司", "target": "未披露", "modality": "bispecific antibody", "importance_level": "高", "total_score": 77.5, "institution_score": 75, "track_score": 85, "milestone_score": 70, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "该CD3+CD7双特异性抗体用于改造lentiviral vector实现in vivo CAR-T基因递送效率提升，针对热门的in vivo CAR-T赛道，Preclinical阶段在小鼠和非人灵长类模型中显示显著改善CAR基因表达。Probio作为GenScript子公司，全球CDMO布局强，in vivo CAR-T+双抗靶向T细胞为高热度领域，故综合评分高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5158", "id": "k1XM_5wBX1NQZOEH-LG6", "source_drug_name": "CD3+CD7 bispecific antibody", "title": "A multipronged approach to improve gene delivery efficiency for in vivo CAR-T using CD3 and CD7 retargeted LVVs", "abstract_text": "Chimeric antigen receptor (CAR)-T therapies have advanced cancer treatment; however, for conventional ex vivo CAR-T therapies, patient access is often hindered by high costs, long manufacturing times, lymphodepleting chemotherapy needed to precondition the patient, and the inconvenience to travel to specialized treatment centers. To address these limitations, strategies have recently emerged to generate CAR-T cells in situ. These approaches, comprising the field of in vivo CAR-T, are based on delivering the CAR construct to T cells in situ typically using either lentiviral vectors (LVV) or lipid nanoparticles (LNP) decorated with T cell-specific antibodies. In vivo CAR-T approaches have demonstrated encouraging efficacy in preclinical and early clinical studies, but still face challenges in terms of efficiency, specificity, durability, and scalability. CD3 and CD7 are well-established T cell targets used in current in vivo CAR-T delivery vehicles, and such LVV and LNP-based approaches are showing encouraging efficacy in CAR gene delivery to T cells in situ; however, the efficiency of current approaches based on monospecific CD3 or CD7 antibodies for in vivo gene delivery still remains low, thereby limiting their therapeutic potency. By using internally developed CD3 and CD7 VHH antibodies, we implemented a multipronged approach to improve the gene delivery efficiency in vivo, including 1) incorporation of a CD3+CD7 bispecific antibody in the LVV particle; 2) inclusion of a HIV component in the LVV particles that counteracts host antiviral defense mechanisms to enhance transgene expression; 3) co-administration of an approved cardiovascular drug that enhances CD7 expression in T cells. In vitro assays in a T cell line and primary T cells and in vivo studies with mice and non-human primates demonstrated that these novel approaches and their combinations substantially improved CAR gene expression compared with CD3 or CD7 monospecific-targeted LVVs.", "source_company": "Probio Inc", "source_org_type": "公司", "row_number": 408, "target_meta": "not available", "MOA_meta": "双特异性抗体"}, {"drug_name": "novel eIF4A inhibitor", "company": "Zymeworks Inc.", "org_type": "公司", "target": "eIF4A", "modality": "ADC", "importance_level": "高", "total_score": 77.5, "institution_score": 85, "track_score": 80, "milestone_score": 60, "field_heat_score": 75, "bonus_score": 5, "brief_reason": "新型eIF4A抑制剂作为ADC payload，具有阻断MYC/KRAS等癌基因翻译的新机制，可克服camptothecin类ADC耐药。Zymeworks为ADC领域头部biotech，赛道热门且具创新性，但仍处preclinical阶段且毒性窗口可能较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6477", "id": "plXM_5wBX1NQZOEH-LS6", "source_drug_name": "novel eIF4A inhibitor", "title": "Design and evaluation of mRNA translation inhibitors for use as antibody drug conjugate payloads", "abstract_text": "Introduction: Eukaryotic initiation factor 4A (eIF4A) mediates recruitment of ribosomes to mRNA and catalyzes the unwinding of mRNA secondary structure, thereby facilitating ribosome scanning and translation initiation. Inhibitors of eIF4A (e.g., silvestrol, zotatifin, and other rocaglates) block translation of select mRNAs that contain a high degree of secondary structure (e.g. mRNAs encoding MYC, KRAS, and CDK4/6, among others), resulting in inhibition of cell proliferation and induction of apoptosis. Despite limited efficacy observed for zotatifin in a phase I clinical trial, antibody conjugation of a novel eIF4A payload offers the possibility of enhanced exposure and improved tolerability, which could lead to more robust responses. Furthermore, eIF4A antibody-drug conjugates (ADCs) would constitute a novel mechanism with the potential to address payload-specific resistance mechanisms that have been reported following progression on ADCs with camptothecin payloads.\nMethods: A panel of novel rocaglamide-derived eIF4A inhibitors containing linkable functional groups were synthesized and evaluated for potency, hydrophilicity, and DMPK properties. Select analogs were elaborated into drug-linkers containing a hydrophilic polyethylene glycol (PEG) side chain to minimize hydrophobicity. Conjugation to endogenous cysteines using maleimide chemistry provided ADCs targeting diverse tumor associated antigens that were evaluated for in vitro potency, in vivo efficacy, and tolerability.\nResults: ADCs carrying eIF4A inhibitors with a drug-to-antibody ratio of 8 required use of hydrophilic PEG groups to minimize aggregation. In vitro, trastuzumab ADCs showed potent antigen-dependent activity in HER2-expressing cell lines and bystander activity in mixed co-cultures of HER2+ and HER2- cells. Selection of lead drug-linkers was based on robust in vivo anti-tumor activity of HER2 targeted ADCs in NCI-N87 and SKOV-3 CDX models as well as tolerability in non-tumor bearing mice and Sprague Dawley rats. The breadth of efficacy of the lead drug-linkers was evaluated in vivo using Ly6E, PTK7, TROP2, cMET, and EGFR targeted ADCs.\nConclusions: Novel eIF4A ADCs constructed using hydrophilic drug linkers demonstrated potent and target-specific in vitro cytotoxicity. Promising in vivo efficacy was observed across multiple tumor associated targets, however the observed toxicity level in both mice and rats suggests a potentially lower than anticipated preclinical therapeutic window.", "source_company": "Zymeworks Inc.", "source_org_type": "公司", "row_number": 953, "target_meta": "eIF4A", "MOA_meta": "抗体偶联药物"}, {"drug_name": "ROR1 CAR T cells armored with IL18", "company": "Miltenyi Biotec", "org_type": "公司", "target": "ROR1", "modality": "CAR", "importance_level": "高", "total_score": 77.5, "institution_score": 75, "track_score": 85, "milestone_score": 70, "field_heat_score": 80, "bonus_score": 4, "brief_reason": "靶向ROR1的CAR-T细胞通过IL18装甲增强扩增、持久性和抗胰腺癌活性，Miltenyi Biotec作为细胞治疗领域领先工具与疗法开发公司具有较强实力。赛道为热门CAR-T+细胞因子装甲策略，在实体瘤尤其是胰腺癌中显示显著体内外优效，preclinical数据清晰有力。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5221", "id": "eZ7ECZ0BZznHJdntvNYd", "source_drug_name": "ROR1 CAR T cells armored with IL18", "title": "Armoring ROR1 CAR T cells with IL18 improves CAR T cell function and cytotoxicity against pancreatic cancer cell-lines in vitro and in vivo", "abstract_text": "ROR1 (Receptor tyrosine kinase-like Orphan Receptor 1) is a tumor-associated antigen widely expressed in solid tumors and is a promising target for CAR T cell therapy in pancreatic cancer. Cell-based immunotherapy has met with limited success due in part to the immunosuppressive tumor microenvironment (TME). Here we demonstrate that armoring our previously described1 ROR1 CAR T cell product with interleukin-18 (IL18) enhanced expansion, persistence, and antitumor efficacy against pancreatic cell lines both in vitro and in vivo.\nROR-1-specific CAR-T cells were generated in human T cells using lentiviral vectors (LV) expressing a second generation CAR alone, CAR+ constitutive IL-18, or CAR+NFAT-IL18. IL18-ROR1 CAR T cells expanded 1.5 fold more, preserved naïve phenotype, and had reduced LAG3 expression (37% vs 81%) vs CAR. In vitro armored CAR cytotoxicity, determined by xCelligence tumor co-culture assays, was equal to or greater than CAR alone against ROR1(+) tumor cell lines. In an AsPC-1 mouse xenograft model, each CAR construct exhibited anti-tumor efficacy, with IL-18 expressing CARs displaying significantly greater tumor control. The constitutive IL18-CAR completely cleared tumor at day 28 post-T cell infusion and showed increased persistence throughout the study when compared to ROR1 CAR-T lacking IL-18 (Fig.1). CAR+NFAT-IL18 similarly controlled tumor growth compared to UTD.\nIn summary, IL18 armored CAR T cells significantly improved the expansion, persistence, and antitumor efficacy of ROR1 CARs in pancreatic cancer xenograft models. Importantly, NFAT-promoter-based regulation of ROR1 CAR T may offer a viable approach to regulating potential toxicity while retaining boosted IL-18 induced activity. This armoring strategy may offer a promising approach solid tumor indications and warrants further preclinical and translational investigation.\nA\nB\nFig 1. In vivo demonstration of effective constitutive and inducible IL18 armoring of ROR1 CAR T targeting pancreatic cell-lines. *p<0.05, **p<0.01, ***p<0.001\nReference:\n1. Tran TM et al. J Immunother Cancer 2024;12(4)", "source_company": "Miltenyi Biotec", "source_org_type": "公司", "row_number": 955, "target_meta": "ROR1", "MOA_meta": "其他"}, {"drug_name": "MAGEA1-specific TCRs derived from RenTCR platform", "company": "Biocytogen", "org_type": "公司", "target": "MAGEA1", "modality": "CAR", "importance_level": "高", "total_score": 77.5, "institution_score": 75, "track_score": 85, "milestone_score": 70, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "靶点为癌-睾丸抗原MAGEA1，RenTCR平台生成的高亲和力TCR显示优于常规来源的肽敏感性和体内外抗肿瘤活性。公司为国内头部biotech，TCR细胞治疗赛道热度高，preclinical数据强劲包括肿瘤消退和无交叉反应。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4551", "id": "dp7M_5wBZznHJdnt_W3O", "source_drug_name": "MAGEA1-specific TCRs derived from RenTCR platform", "title": "RenTCR-derived MAGEA1-specific TCRs demonstrated superior peptide sensitivity and potent antitumor activity in vitro and in vivo", "abstract_text": "Background: MAGEA1, a cancer-testis antigen, is broadly expressed in solid tumors such as HCC and NSCLC, but is restricted to the testis in normal tissues, making it an ideal therapeutic target. TCR therapies against MAGEA1 are in preclinical/early clinical stages. Conventional strategies for TCR discovery typically rely on isolation from donor PBMCs or patient TILs. In contrast, Biocytogen's proprietary RenTCR platform enables the generation of TCRs using TCR/MHC humanized mouse models. Lacking thymic negative selection to human antigens, this platform facilitates the identification of TCRs exhibiting higher reactivity and specificity.\nMethod: RenTCR mice (HLA-A*02:01) were immunized with full-length MAGEA1 mRNA. PBMCs or splenocytes were isolated and stimulated in vitro with artificially modified antigen-presenting cells (APCs) presenting MAGEA1. Activated antigen-specific CD8+ T cells were then sorted. Single cells were sorted by FACS for reverse transcription, amplification, and sequencing to obtain TCR sequences. Initial TCR screening used a Jurkat reporter assay for binding. Positive TCRs were transduced into primary human T cells and co-cultured with HLA-A2.1+/MAGEA1+ tumor cells to assess killing and cytokine release. Functional TCR candidates underwent off-target risk assessment, with final anti-tumor efficacy validated in CDX models using NDG mice.\nResults: Immunization of 20 mice yielded a total of 80 binding-positive TCRs. The majority of these TCRs mediated potent cytotoxic activity in vitro. Assessment of functional avidity showed that TCRs derived from RenTCR mice recognized target peptides with superior sensitivity compared to human donor-derived TCRs. No cross-reactivity was detected in the candidate TCRs. All candidate TCRs demonstrated efficacy by inducing tumor regression in NDG mice bearing HLA-A2.1+/MAGEA1+ tumors.\nConclusion: The RenTCR platform enables the generation of T cell receptors (TCRs) with higher reactivity and specificity. TCRs derived from RenTCR mice exhibited better peptide sensitivity than human donor-derived TCRs. The candidate TCRs demonstrated excellent antitumor activity both in vitro and in vivo.", "source_company": "Biocytogen", "source_org_type": "公司", "row_number": 1029, "target_meta": "MAGEA1", "MOA_meta": "其他"}, {"drug_name": "SHR-RAS001", "company": "ShangHai Hengrui Pharmaceuticals Co., Ltd.", "org_type": "公司", "target": "RASmulti(ON)", "modality": "inhibitor", "importance_level": "高", "total_score": 77.3, "institution_score": 85, "track_score": 95, "milestone_score": 40, "field_heat_score": 90, "bonus_score": 3, "brief_reason": "SHR-RAS001为结构新颖的高效tri-complex RAS multi(ON)抑制剂，靶向RAS活性态，多选择性抑制具有极高赛道热度。恒瑞作为国内TOP pharma机构实力强，但摘要禁运仅为Discovery阶段，里程碑信息有限。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11454", "id": "kJ7M_5wBZznHJdnt_W3O", "source_drug_name": "SHR-RAS001", "title": "Discovery and identification of SHR-RAS001: A structurally novel, highly potent tri-complex RASmulti(ON) inhibitor", "abstract_text": "Abstract is embargoed at this time.", "source_company": "ShangHai Hengrui Pharmaceuticals Co., Ltd.", "source_org_type": "公司", "row_number": 270, "target_meta": "not available", "MOA_meta": "抑制剂"}, {"drug_name": "a panel of VHH binders against LGR5", "company": "BioMap Inc", "org_type": "公司", "target": "LGR5", "modality": "VHH", "importance_level": "高", "total_score": 77, "institution_score": 75, "track_score": 85, "milestone_score": 70, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "针对LGR5的AI驱动de novo VHH纳米抗体面板，LGR5为癌干细胞标志物且具药物可成药性，BioMap作为AI+生物科技头部公司结合热门VHH模态和新兴靶点；preclinical阶段展示多表位覆盖、高亲和力、优异稳定性和制造性，AI优化加速开发具亮点。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5505", "id": "dJ7M_5wBZznHJdnt_W7P", "source_drug_name": "a panel of VHH binders against LGR5", "title": "Diverse VHH antibodies targeting multiple LGR5 epitopes for cancer therapy", "abstract_text": "Background: LGR5 is a validated therapeutic target highly expressed in cancer stem cells and solid tumors. Petosemtamab, an EGFR/LGR5 bispecific antibody, confirms its druggability. Single-domain antibodies (VHHs) provide advantages over conventional antibodies through small size, high tissue penetration, and scalable manufacturing. We aimed to create a panel of VHH binders against LGR5 with broad epitope diversity and favorable biophysical traits for therapeutic use.\nMethods: VHHs were designed using AI-based structure and sequence-guided modeling targeting recombinant human LGR5 extracellular domain. Chain-of-thought optimization was applied to improve multiple parameters simultaneously, including affinity, thermal stability (Tm), expression yield, and hydrophobic interaction chromatography (HIC) behavior. Top candidates were evaluated for kinetics via surface plasmon resonance, epitope mapping by cryo-EM using N-glycan knockout variants, thermal stability by differential scanning fluorimetry, and expression in mammalian systems. Specificity was tested against related receptors LGR4 and LGR6.\nResults: Multiple VHH clones showed high-affinity binding to LGR5, with KD values in the nanomolar range. Cryo-EM mapping revealed distinct, non-overlapping epitopes across the LGR5 extracellular domain, providing full structural coverage of potential binding sites. The panel included both LGR5-selective and pan-LGR binders, offering flexibility in therapeutic design. R-spondin competition assays identified ligand-blocking and non-competing VHHs targeting alternate epitopes. All lead molecules displayed strong stability (Tm >65°C) and robust expression, supporting high manufacturability. These characteristics enable both pathway inhibition and targeted payload delivery approaches to eliminate LGR5+ cancer stem cells.\nConclusions: AI-driven protein engineering produced a diverse, high-quality panel of LGR5-targeted VHHs with multi-epitope coverage, broad affinity range, and strong manufacturability. Chain-of-thought optimization improved multiple parameters in parallel, accelerating VHH development. This library enables rational design of bispecific and multispecific therapeutics for enhanced tumor targeting and represents a foundation for next-generation LGR5-directed ADCs, bispecifics, and CAR-T therapies.", "source_company": "BioMap Inc", "source_org_type": "公司", "row_number": 101, "target_meta": "LGR5", "MOA_meta": "单域抗体"}, {"drug_name": "CAP-IL-12 DNA-LNP", "company": "Earli Inc.", "org_type": "公司", "target": "未披露", "modality": "other", "importance_level": "高", "total_score": 77, "institution_score": 75, "track_score": 85, "milestone_score": 70, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "CAP-IL-12 DNA-LNP利用癌特异启动子驱动IL-12表达并结合DNA引发的cGAS-STING先天免疫激活，实现肿瘤选择性免疫治疗，靶点未明确披露但机制新颖。Earli作为获超1亿美元融资的创新biotech（顶级VC如a16z、Khosla投资），赛道为热门基因治疗+LNP+STING激活，动物模型显示完全持久肿瘤消退，故综合评分高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10419", "id": "NZ7ECZ0BZznHJdntvNYd", "source_drug_name": "CAP-IL-12 DNA-LNP", "title": "Leveraging cancer-activated gene expression and cGAS-STING activation for efficient tumor killing via a DNA-LNP delivery platform", "abstract_text": "Background: Despite rapid advances in immunotherapy, the clinical use of potent immune-modulating agents remains constrained by systemic toxicities. Earli is developing a DNA-based immunotherapy platform that uses synthetic cancer-activated promoters (CAPs) to drive selective expression of therapeutic payloads in malignant cells, while remaining silent in normal tissues and benign lesions. DNA is delivered systemically to the tumor cells by lipid nanoparticles (LNPs). The platform also engages innate immunity via the immunostimulatory nature of DNA. This study highlights the dual mechanism of combining 1) CAP-driven expression of a potent immunostimulatory payload such as IL-12 with 2) cGAS-STING-induced innate immune activation.\nMethods: Naïve or tumor-bearing mice were treated with LNPs encapsulating either a DNA nanoplasmid encoding IL-12 under a cancer-activated promoter (CAP-IL-12) or a matched construct with three stop codons (Control-DNA). Mice were assessed for tumor growth inhibition, cytokines (IL-6, IL-1β, TNF-α), and IL-12 levels in tumor and serum.\nResults: LNP encapsulating Control-DNA increased transcript levels of STING downstream targets and triggered a transient rise in pro-inflammatory cytokines. This innate immune response resulted in a partial (i.e. non-durable) inhibition of tumor growth across multiple syngeneic tumor models and showed enhanced efficacy when combined with PD-1 checkpoint blockade. Importantly, in STING knockout mice, the anti-tumor response to the formulated Control-DNA was completely lost. In contrast, IV treatment with an LNP encapsulating CAP-IL-12 DNA led to complete and durable tumor regression. Surprisingly, although modest IL-12 protein was detectable in tumors, there were no substantial IL-12 levels measured in serum, demonstrating the platform's ability to concentrate a highly potent therapeutic at the tumor site while avoiding systemic exposure. Further, immune profiling showed both IL-12 and STING induced changes including increases in T cell and NK cell proliferation, granzyme B upregulation, and enhanced myeloid activation and antigen presentation. Importantly, the anti-tumor efficacy of CAP-IL-12 was retained in syngeneic tumors in STING knockout mice, demonstrating that cancer-specific payload expression is sufficient to drive efficacy even in the absence of adjuvant STING agonism. Our current work focuses on modulating STING agonism through LNP engineering approaches to fine-tune its activity in the tumor for a balanced therapeutic response.\nConclusions: Overall, our findings highlight the dual-function nature of Earli’s DNA-LNP platform: a programmable, tumor-selective gene therapy system with built-in innate immune activation through STING agonism. The approach supports a new class of immunotherapies that combine precision and potency in a single genetic modality.", "source_company": "Earli Inc.", "source_org_type": "公司", "row_number": 403, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "a novel LNP composition", "company": "Cytiva", "org_type": "公司", "target": "未披露", "modality": "other", "importance_level": "高", "total_score": 77, "institution_score": 75, "track_score": 85, "milestone_score": 70, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "该新型LNP用于非病毒CRISPR HDR基因插入实现原代T细胞高效敲入，靶点未明确披露但聚焦细胞基因治疗交付系统。Cytiva作为Danaher旗下生命科学工具巨头在工具/平台领域有较强实力，LNP+CRISPR赛道热度高且实现临床相关敲入频率+显著优于电转的细胞产量，整体潜力较大。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5553", "id": "O1XM_5wBX1NQZOEH-LO6", "source_drug_name": "a novel LNP composition", "title": "Lipid nanoparticles enable high efficiency CRISPR HDR mediated gene insertions in primary human T cells", "abstract_text": "Stable gene insertion using non-viral delivery is essential to unlocking the next generation of safe and accessible cell and gene therapies. Currently, viral vectors carry high manufacturing costs and insertional mutagenesis concerns, while electroporation (EP) affects cell yield and viability. Lipid nanoparticles (LNPs) can be a promising alternative option for engineering cells for persistent expression of target genes, as they offer a favorable safety profile and are both cost-effective and scalable. In this work, we mapped out the critical parameters governing homology-directed repair (HDR) in primary T cells using LNP-mediated cargo delivery. Cas9 mRNA, a chemically synthesized guide RNA (sgRNA), and an ~100 nt single-stranded donor oligonucleotide (ssODN) were encapsulated within a novel LNP composition using a scalable production platform. A haemagglutinin (HA) epitope tag was knocked in at the CD5 locus as an easily quantified read-out for parameter optimization. CD3+ primary T cells from healthy donors were cultured in well-plates and the CRISPR LNPs added to the media in a one-step process, without further cell manipulation. Various parameters were identified and systematically varied, including (and not limited to) the length of cell activation, cell density, nucleic acid dose and the RNA/DNA molar ratios. Through multiple rounds of optimization, LNPs achieved on average 31 ± 7% HDR in n=5 T cell donors, detected through dual CD5/HA flow cytometry 4 days post-LNP administration. Viability of the cells remained high at 96 ± 5% at the time of HDR detection, relative to untreated controls. The aforementioned results reflect no added enhancers; however, when we tested various small molecules, such as NHEJ inhibitors, HDR rates further improved to over 50% in primary T cells. Finally, we compared the optimized LNP protocol to EP which resulted in similar HA+ frequencies. However, most notably, the yield of viable edited cells by LNP was an order of magnitude higher than EP owing to improved cell viability and proliferation. All together, this data demonstrates how LNPs can achieve clinically relevant knock-in frequencies and showcases the benefits of LNPs as a non-viral alternative for gene insertion. This approach for parameter optimization is applicable for a diverse set of therapeutic loci, providing a framework for the rapid application of LNPs to enable the next generation of T cell therapies.", "source_company": "Cytiva", "source_org_type": "公司", "row_number": 694, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "ON-BOARD™", "company": "OncoNano Medicine, Inc.", "org_type": "公司", "target": "未披露", "modality": "other", "importance_level": "高", "total_score": 77, "institution_score": 75, "track_score": 85, "milestone_score": 70, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "ON-BOARD™为超pH敏感聚合物胶束平台，通过酸性肿瘤微环境靶向递送细胞毒药物，实现肿瘤特异性释放，独立于特定靶点表达。机构为有Gilead合作及临床验证技术的美国biotech，赛道为新型纳米递送平台具创新性，preclinical显示优于对照药的强效与耐受性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5567", "id": "cFXM_5wBX1NQZOEH-LO6", "source_drug_name": "ON-BOARD™", "title": "A polymer-drug conjugate platform for tumor specific drug delivery: Advancement of a clinically validated ultra pH-sensitive micelle technology", "abstract_text": "Background: Antibody-drug conjugates (ADCs) have been developed to deliver anti-tumor therapeutics directly to tumors, and have demonstrated some impressive clinical benefits. Challenges with ADCs, however, persist, including necessary identification of exclusively or highly expressed tumor targets, emergence of resistance due to target downregulation, and systemic toxicities from both off-tumor/on-target deployment of payload or unplanned payload release. Herein, we report a polymer-drug conjugate (PDC) platform based on a clinically-validated, ultra-pH sensitive micelle technology - ON-BOARD™. This novel technology enables delivery of cytotoxic compounds through targeting the acidic tumor microenvironment (TME), independent of tumor target expression, offering a differentiated approach from existing therapeutics.\nMethods: A pilot library of pH sensitive ON-BOARD™ PDCs was synthesized, connecting clinically utilized warheads (DM1, MMAE, SN-38) via cleavable or non-cleavable linkers. Purity and drug-to-polymer ratio (DPR) were characterized by HPLC and 1H NMR. PDC micelles were characterized for purity, particle size, and pH-responsiveness. Linker reactivities were confirmed by treating formulations under cleavage-inducing conditions. In vitro cytotoxicity was evaluated by incubation with different cancer cell lines. In vivo anti-tumor efficacy and tolerability were demonstrated in mice bearing human colon cancer xenografts (HCT-116, HT-29) and compared with a standard chemotherapy and/or the corresponding free drug.\nResults: The PDC polymers were synthesized with high purities (>95%) and DPR ranging from 2 to 4. The formulated micelles showed sharp pH responsiveness with particle size < 60 nm and an expected > 1,000 drug per micelle ratio. In vitro treatment of the cleavable PDC micelles confirmed the reactivity according to their respective linker cleavage mechanisms. Cytotoxicity assays in multiple cancer cell lines showed directed payload release with PDCs containing certain cleavable linkers showing strong potency upon triggering of drug release. DM1 and SN38 PDCs with a cleavable linker demonstrated stronger antitumor activity compared to the ones with a non-cleavable linker in HCT-116 and HT-29 tumors in mice, respectively, while a cleavable SN-38 PDC showed superior efficacy to irinotecan (76% vs 48% TGI) at 21-fold lower SN-38 equivalent dose. MMAE PDCs with cleavable linkers achieved strong efficacy in HT-29 model (99% TGI, 88-100% tumor free) with favorable tolerability compared to the docetaxel control.\nConclusion: A variety of PDCs with different linker drug combinations were generated with ON-BOARD™ pH sensitive micelle technology. The resultant formulations demonstrated strong potency in vitro and in vivo, offering a promising platform for delivery of therapeutics to the TME with high specificity.", "source_company": "OncoNano Medicine, Inc.", "source_org_type": "公司", "row_number": 725, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "EXP012", "company": "Lepu Biopharma Co., Ltd", "org_type": "公司", "target": "CDH17", "modality": "TCE", "importance_level": "高", "total_score": 77, "institution_score": 70, "track_score": 90, "milestone_score": 70, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "EXP012为靶向CDH17的三特异性T细胞衔接剂（tri-specific TCE），整合CD3和4-1BB共刺激，针对胃肠道癌症的冷肿瘤；Lepu作为国内专注肿瘤的创新biotech公司实力较强，tri-specific TCE+4-1BB机制新兴热门，preclinical数据强劲包括猴毒理安全、肿瘤抑制和生存延长，支持临床推进。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4546", "id": "hVXM_5wBX1NQZOEH-LO6", "source_drug_name": "EXP012", "title": "A next-generation tri-specific T cell engager targeting CDH17 with 4-1BB co-stimulation for the treatment of gastrointestinal cancers", "abstract_text": "Background: Cadherin-17 (CDH17), a membranous cell adhesion protein, is highly expressed in gastrointestinal (GI) cancers, particularly in colorectal cancer. In normal intestine tissue, CDH17 is restricted to the lateral side of the epithelial cells and remains largely inaccessible to antibody, making it a promising therapeutic target for GI malignancies. Our platform has demonstrated that incorporating 4-1BB costimulation can effectively convert immunologically \"cold\" tumors into \"hot\". This transformation is achieved by enhancing the infiltration of peripheral T cells into the tumor and systemically remodeling the tumor microenvironment. Moreover, this strategy elicits a durable T cell memory response and significantly prolongs survival. Given that GI cancer is a classic \"cold\" tumor, we have developed a novel tri-specific T cell engager (TCE) that targets CDH17 on cancer cells and engages CD3 and 4-1BB on T cells. This TCE is engineered to redirect and enhance T cell responses against CDH17-expressing tumor cells. With a manageable safety profile, this approach holds strong potential to improve clinical outcomes for patients with GI cancers.\nMethods: The in vitro activities of the CDH17-CD3-4-1BB tri-specific TCE were evaluated in both CDH17-positive and -negative tumor cell lines. These assessments included T cell-mediated cytotoxicity, T cell activation, cytokine release and T cell proliferation. In vivo anti-tumor activity was investigated in two models: a humanized syngeneic mice model bearing B16F10-hCDH17 tumors and NCG-MHC-dKO mice with human PBMC bearing Lovo tumors. Cytokine release assay (CRA) was conducted to evaluate potential cytokine storm risk. Additionally, the toxicological profile was assessed in a pilot toxicity study in cynomolgus monkeys.\nResults: CDH17-CD3-4-1BB tri-specific TCE demonstrated CDH17-dependent activation of CD3 and 4-1BB. It effectively induced tumor lysis in multiple CDH17+ tumor cell lines and significantly enhanced T cell activation, cytokine production and T cell proliferation in the presence of CDH17-expressing target cells. In humanized syngeneic tumor mouse model and human PBMC xenograft tumor mouse model, this molecule demonstrated robust tumor growth inhibition and prolonged survival rate. Furthermore, an in vitro CRA indicated lower IL-6 release compared to a clinical benchmark, indicating a more manageable risk of cytokine release syndrome (CRS). In the pilot tox study, no adverse effects were observed in clinical signs and histopathology.\nConclusion: CDH17-CD3-4-1BB tri-specific TCE represents a novel CDH17-targeted T cell engager with potent and durable anti-tumor activity. Collectively, these results underscore its potential as a novel therapeutic agent against GI cancers and support its advancement into clinical development.", "source_company": "Lepu Biopharma Co., Ltd", "source_org_type": "公司", "row_number": 741, "target_meta": "CDH17", "MOA_meta": "其他"}, {"drug_name": "antisense oligonucleotide targeting SEAL1", "company": "HAYA Therapeutics INC", "org_type": "公司", "target": "SEAL1", "modality": "ASO", "importance_level": "高", "total_score": 77, "institution_score": 75, "track_score": 85, "milestone_score": 70, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "药物为针对新型lncRNA SEAL1的ASO，可显著抑制pan-cancer myCAF细胞状态，改善肿瘤微环境并增强治疗敏感性。HAYA为国外头部biotech（获Lilly合作及6500万美元A轮融资），小核酸+新型调控靶点赛道热度高，体外/体内模型显示强preclinical效果，故综合评分较高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10790", "id": "Z57M_5wBZznHJdnt_W3O", "source_drug_name": "antisense oligonucleotide targeting SEAL1", "title": "The novel lncRNA SEAL1 - key regulator of the pan-cancer myCAF cell state dictating prognosis ans immunotherapy response - is a promising new therapeutic target for solid cancers", "abstract_text": "A desmoplastic reaction in the solid tumor microenvironment (TME), typically characterized by extracellular matrix (ECM) dysregulation and an immune suppressive milieu, is a key factor contributing to tumor aggression, therapeutic resistance, metastasis and inevitably poor patient prognosis. Cancer-associated fibroblasts (CAFs), in particular myofibroblast-like CAFs (myCAFs), are central players in the development of TME desmoplasia in the most common and aggressive solid cancers such as breast, lung, head & neck and pancreatic. The contribution of myCAFs to standard-of-care treatment resistance and immunotherapy failure has raised their attraction as therapeutic targets. However, myCAF-targeting therapies have not yet proven to be effective for clinical use and is still a largely unexplored area of solid cancer therapeutics. Long non-coding RNAs (lncRNAs) are increasingly recognized as key regulators of epigenomic and transcriptomic cellular processes and characterized by highly cell-state and disease-specific expression. Targeting myCAF-specific regulatory lncRNAs constitutes a novel therapeutic approach to reduce myCAF-driven detrimental changes in the TME, coupled to an increased susceptibility to combination treatments. Here we identified a novel lncRNA SEAL1 which is restrictively expressed in the pan-cancer myCAF cell state associated with poor patient prognosis and treatment response. Independent analyses of breast, head & neck and pancreatic cancer patient datasets demonstrated SEAL1 as a key component of disease-driving myCAF co-regulatory networks. By antisense oligonucleotide (ASO)-mediated targeting of SEAL1, and of the murine functional analog Seal1, we demonstrated that the myCAF identity was potently reduced in in vitro cellular models. In contrast, ASO- or CRISPRi-mediated targeting of LRRC15/Lrrc15, a SEAL1 downstream marker associated with the myCAF cell identity, had no effect on the disease-driving myCAF cell state. LRRC15 has previously been associated with poor prognosis and an unfavorable response to immunotherapy, being actively pursued as a potential CAF therapeutic target. Moreover, by utilizing a xenograft co-injection in vivo model, SEAL1 targeting in patient-derived myCAFs reduced tumor volume whereas LRRC15 targeting had no effect. Taken together, this study emphasizes that the Regulatory Genome is still largely under explored and that novel discoveries such as SEAL1 may uncover previously unknown biological mechanisms. By leveraging regulatory lncRNAs as potent modifiers of specific disease-states, we conclude that the SEAL1 lncRNA is a major determinant of myCAF pro-tumorigenic transcriptional programs of therapeutic value.", "source_company": "HAYA Therapeutics INC\nHAYA Therapeutics\nHAYA Therapeutics SA", "source_org_type": "公司", "row_number": 1019, "target_meta": "not available", "MOA_meta": "反义疗法"}, {"drug_name": "Membrane Proteome Array", "company": "Integral Molecular", "org_type": "公司", "target": "未披露", "modality": "other", "importance_level": "高", "total_score": 76.5, "institution_score": 75, "track_score": 70, "milestone_score": 85, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "Membrane Proteome Array（MPA）是Integral Molecular开发的用于抗体药物特异性检测的细胞基蛋白阵列平台，非治疗性药物而是药物开发工具。机构为专注膜蛋白技术的专业biotech公司且在FDA ISTAND程序中接近DDT资格认证，里程碑进展显著，赛道为抗体开发关键安全性工具具监管潜力，故综合评分较高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5648", "id": "n57M_5wBZznHJdnt_W3O", "source_drug_name": "Membrane Proteome Array", "title": "A new approach methodology (NAM) for specificity testing: ISTAND qualification of the membrane proteome array to evaluate off-target binding of MAb-based therapies", "abstract_text": "Background: Scientifically validated New Approach Methodologies (NAMs) provide an opportunity to better predict drug safety in humans while also accelerating drug development and regulatory review. The FDA has established pathways to qualify NAMs as Drug Development Tools (DDTs) through various mechanisms that now include the Innovative Science and Technology Approaches for New Drugs (ISTAND) program.\nMethods: We developed the Membrane Proteome Array (MPA) platform for specificity testing of antibody-based therapeutics. The MPA assesses binding interactions across ~6,000 membrane proteins, each individually expressed in their native structural configuration within live or unfixed cells. The screen uses high-throughput flow cytometry, allowing for quantitative and high-sensitivity detection, and any identified targets are validated by titration analysis. The MPA is being qualified as a novel DDT through FDA’s ISTAND program.\nResults: As part of our DDT qualification, we performed a comparison study of 35 antibody therapeutics evaluated for specificity using both our MPA and conventional tissue cross-reactivity (TCR) studies. We found that 17% of these drugs had an off-target that was not expected based on TCR results. Overall, the MPA and TCR results were consistent for only about half of the molecules tested. In numerous instances, TCR results were inconclusive based on technical variability, nonspecific or cytoplasmic staining, or false-positive staining. Such results highlight the difficulty of using TCR data for deciding actionable next steps. In contrast, off-targets from the MPA are de-risked by statistically quantifying relative affinity and binding levels, localizing binding to extracellular vs. intracellular epitopes, and determining tissue expression patterns in humans to assess the in vivo safety risk. Through the MPA qualification process, we have also quantified the sensitivity and reproducibility of the platform and implemented additional quality control procedures and data analyses.\nConclusions: MPA data is already routinely used in regulatory applications for antibody-based biotherapeutics and may be used to replace or complement other cross-reactivity studies. The MPA is currently in the last stages of review for DDT qualification through FDA’s ISTAND program.", "source_company": "Integral Molecular", "source_org_type": "公司", "row_number": 88, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "ZMS-4426", "company": "Simcere Zaiming Pharmaceutical Co., Ltd.", "org_type": "公司", "target": "SMARCA2", "modality": "degrader", "importance_level": "高", "total_score": 76.5, "institution_score": 75, "track_score": 85, "milestone_score": 70, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "ZMS-4426为高度选择性口服SMARCA2降解剂，针对SMARCA4缺失癌利用合成致死机制，体外/体内显示强抗瘤活性但种属体内选择性差。Simcere Zaiming作为国内肿瘤创新药头部公司+热门PROTAC-like降解剂赛道+良好口服PK及CDX模型TGI但犬/猴体内耐受性及选择性问题，综合热度高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8719", "id": "QVXM_5wBX1NQZOEH-LS6", "source_drug_name": "ZMS-4426", "title": "ZMS-4426, an oral degrader of SMARCA2 shows potent anti-tumor activity, but variant selectivity against SMARCA4 across species", "abstract_text": "Mammalian SWI/SNF complexes always contain one of two mutually exclusive and structurally highly related ATPases: SMARCA2/BRM or SMARCA4/BRG1, as its catalytic subunit. It is reported that SMARCA4 is absent in a serial of cancers, and these SMARCA4 deficient cancer cells are highly dependent on its paralog SMARCA2 for survival. Therefore, it holds great therapeutic promise to treat SMARCA4 deficient cancers with selective SMARCA2 degraders. Here, we reported ZMS-4426, a highly selective SMARCA2 degrader. In HiBiT knock-in HeLa cells, it potently degraded SMARCA2 with a >10,000-fold selectivity over SMARCA4. The global proteome data also indicated that ZMS-4426 was highly specific in degrading the expected target proteins SMARCA2. Furthermore, ZMS-4426 demonstrated high degradation selectivity of SMARCA2 over SMARCA4 in a variety of human cancer cell lines and PBMCs of multiple species. However, in dog PBMCs, the degradation selectivity between SMARCA2 and SMARCA4 varies among individuals.Due to the high selectivity over SMARCA4, ZMS-4426 effectively inhibited the proliferation of SMARCA4 deficient cells, and inhibited the proliferation of neither SMARCA2/4-WT cells nor SMARCA2/4-DEL cells. Furthermore, the in vitro synergistic effects were observed when SMARCA4-loss NSCLC cells were treated with ZMS-4426 in combination with docetaxel.ZMS-4426 exhibited good oral availability in mice, rats, and dog. In the NSCLC NCI-H838 CDX model, ZMS-4426 effectively inhibited tumor growth, and the tumor growth inhibition (TGI) correlated well with SMARCA2 degradation in tumors. Further, the combination treatment of ZMS-4426 and nab-paclitaxel effectively suppressed tumor growth to a greater extent than either agent alone.\nHowever, ZMS-4426 was not tolerated in dog for 7-day treatment at 2 mpk. Strong degradation of SMARCA4 in lung was detected, suggesting poor in vivo degradation selectivity in dog. Further, in monkey, the treatment of ZMS-4426 for 7-day at 1.5 mpk resulted in body weight loss and deep degradation of SMARCA4 in PBMCs, indicating that in vitro degradation selectivity in monkey PBMCs did not maintained in vivo.Similar findings were also observed in rats. In a head-to-head comparison with compound A (a reference molecule from WO2025194405, Prelude Therapeutics), treatment of ZMS-4426 and compound A for 4-day at 5 mpk intravenous injection in rats both induced complete degradation of SMARCA4 at 24 hours post-dose, indicating that neither compound preserved its selectivity profile in vivo.In conclusion, our potent and selective SMARCA2 degrader, ZMS-4426 induces strong synthetic lethality in SMARCA4 deficient cells both in vitro and in vivo. However, more studies are needed to elucidate discrepancy in degradation selectivity between in vitro and in vivo results.", "source_company": "Simcere Zaiming Pharmaceutical Co., Ltd.", "source_org_type": "公司", "row_number": 110, "target_meta": "SMARCA2", "MOA_meta": "降解剂"}, {"drug_name": "BCG018", "company": "Biocytogen", "org_type": "公司", "target": "ITGB6", "modality": "ADC", "importance_level": "高", "total_score": 76.5, "institution_score": 75, "track_score": 85, "milestone_score": 65, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "BCG018为靶向ITGB6的ADC，采用新型拓扑异构酶I抑制剂payload，在胰腺癌、结直肠癌和NSCLC的PDX/CDX模型中显示优于benchmark的疗效。Biocytogen作为国内头部biotech平台型公司，ADC+新兴靶点ITGB6赛道热度高，preclinical数据扎实但尚未进入临床。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4467", "id": "kZ7M_5wBZznHJdnt_W3O", "source_drug_name": "BCG018", "title": "Preclinical efficacy of BCG018, an ADC targeting ITGB6 and incorporating a topoisomerase I inhibitor payload, was demonstrated to be effective in PDX models", "abstract_text": "Integrin αvβ6 is a heterodimer composed of αv and β6 subunits that is primarily found on the surfaces of epithelial cells and is known to be upregulated during the epithelial-mesenchymal transition (EMT). Its overexpression in various solid tumors, which correlates with poor patient prognosis, makes it a promising target for ADC therapy. However, the large size and complexity of the integrin family present significant challenges in developing specific antibodies.\nIn our studies, we identified the anti-ITGB6-B antibody, which selectively binds to ITGB6 over other beta integrins. This specificity was established using fully human common light chain RenLite mice with ITGB6 knockout. The anti-ITGB6-B antibody demonstrated good binding affinity for both ITGB6 and its heterodimer αvβ6, outperforming the benchmark, as confirmed by SPR and ELISA experiments.\nFurthermore, anti-ITGB6-B exhibited excellent binding characteristics across multiple tumor cell lines, effectively targeting cells with varying levels of ITGB6 expression. Importantly, its internalization activity was found to be comparable to or greater than that of the benchmark, enhancing its potential for therapeutic applications. Notably, the anti-ITGB6-B did not block the interaction of ITGB6 with its ligand LAP in ELISA assays, indicating its potential as a targeted therapy without disrupting critical signaling pathways. The anti-ITGB6-B also exhibited excellent physicochemical properties and developability, making it a promising candidate for further development in ADC therapy.\nThe anti-ITGB6-B was then conjugated to vcMMAE. The resulting conjugate demonstrated superior efficacy to that of the benchmark ADC in PDX models, regardless of ITGB6 expression levels. Additionally, the BCG018, which is anti-ITGB6-B conjugated with a novel topoisomerase I inhibitor (BLD1102), showed superior efficacy to benchmark ADC in models of pancreatic, colorectal, and NSCLC PDX or CDX xenografts.\nOverall, BCG018 conjugates offer a promising strategy for targeting integrin αvβ6 in solid tumors with specific and potent efficacy.", "source_company": "Biocytogen", "source_org_type": "公司", "row_number": 120, "target_meta": "ITGB6", "MOA_meta": "抗体偶联药物"}, {"drug_name": "RGT-490", "company": "Qilu Regor Therapeutics Inc.", "org_type": "公司", "target": "PI3Kα", "modality": "inhibitor", "importance_level": "高", "total_score": 76.5, "institution_score": 75, "track_score": 85, "milestone_score": 65, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "RGT-490为突变选择性PI3Kα抑制剂（allosteric机制），针对PIK3CA突变肿瘤可减少野生型相关毒性并克服耐药，Qilu Regor作为有海外BD亮点（如与Lilly合作、Genentech收购其他项目）的国内biotech机构实力较强。赛道热度高（突变选择性PI3Kα抑制剂近期多笔大额交易），但仍处临床前向I期过渡阶段。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8829", "id": "ZlXM_5wBX1NQZOEH-LG5", "source_drug_name": "RGT-490", "title": "Discovery and characterization of RGT-490, a mutant selective PI3Kα inhibitor", "abstract_text": "PI3Kα is frequently mutated and overactivated in a variety of human cancers including breast, gynecological, head and neck, and colorectal cancers. Clinical use and efficacy of the approved PI3Kα inhibitors alpelisib and inavolisib are limited by the side effects associated with wild-type (WT) PI3Kα inhibition, prominently hyperglycemia, rash, stomatitis and GI toxicities. RGT-490 is a potent and mutant selective PI3Kα inhibitor discovered by deploying Computer Accelerated Rational Design (CARD) technology platform. It demonstrated potent anti-proliferation activity in PIK3CA mutated cancer cells. In ER+ breast cancer T47D xenograft model, RGT-490 robustly suppressed Akt phosphorylation and induced significant apoptosis without increasing insulin or glucose levels. In addition, RGT-490 caused near-complete tumor regressions in T47D models without any apparent toxicity. As an allosteric PI3Kα inhibitor, RGT-490 overcame the resistance to orthosteric inhibitors alpelisib and inavolisib resulted from the secondary mutations in the ATP binding pocket. In HER2+ breast cancer HCC1954 cells, RGT-490 suppressed the resistance to HER2 inhibition caused by PI3Kα mutation. With potent activity and excellent selectivity, RGT-490 provides opportunity to reduce WT PI3Kα-associated toxicities, enable deeper target coverage and achieve further improved clinical efficacy in PI3Kα mutant patients. RGT-490 phase 1 study is planned 1H2026.", "source_company": "Qilu Regor Therapeutics Inc.", "source_org_type": "公司", "row_number": 126, "target_meta": "PI3Kα", "MOA_meta": "抑制剂"}, {"drug_name": "DR319-DP", "company": "Zhejiang Doer Biologics Co., Ltd", "org_type": "公司", "target": "Nectin-4/Trop-2", "modality": "bispecific ADC", "importance_level": "高", "total_score": 76.5, "institution_score": 65, "track_score": 90, "milestone_score": 75, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "DR319-DP为avidity-driven的Nectin-4/Trop-2双特异性ADC，采用双payload（TopoI+MTI）设计以克服异质性和耐药，靶向热门Trop-2和Nectin-4。机构为国内临床阶段biotech（华东医药旗下），赛道ADC+双靶点+双MOA热度高，preclinical数据强劲包括优于benchmark的CDX/PDX疗效及良好PK，综合潜力突出。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4377", "id": "lVXM_5wBX1NQZOEH-LK6", "source_drug_name": "DR319-DP", "title": "DR319-DP: A Nectin-4/Trop-2 bispecific ADC with an avidity-driven VHH design and dual-MOA payloads", "abstract_text": "Trop-2 and Nectin-4 have emerged as attractive targets for the development of next-generation antibody-drug conjugates (ADCs). However, the emergence of drug resistance remains a critical challenge in ADC therapy. Combination strategies represent a promising approach to enhance therapeutic efficacy and mitigate resistance. Notably, Trop-2 and Nectin-4 exhibit high and frequent co-expression across multiple solid tumors, while showing limited or moderate expression in normal tissues. In clinical attempts, the combination of sacituzumab govitecan (SG) and enfortumab vedotin (EV) has demonstrated substantially improved efficacy in early-phase trials for metastatic urothelial carcinoma. However, toxicities arising from both “off-target, off-tumor” and “on-target, off-tumor” effects remain a major concern. To maximize antitumor efficacy while minimizing systemic toxicity, we developed an avidity-driven bispecific antibody, DR319, featuring a “1+1” bispecific format that incorporates a low-affinity but high-avidity anti-Trop-2 VHH arm. We demonstrated that DR319 enables potent, high-avidity binding to Nectin-4/Trop-2 dual-positive tumor cells in our diverse cell line panel, while minimizing binding to Trop-2 single-positive cells, thereby mechanistically reducing on-target toxicities. We then conjugated DR319 to a novel Topoisomerase I inhibitor (TopoI) linker-payload (CPD3) featuring improved plasma stability, generating DR319-CPD3 (DAR 6). Our results showed that DR319-CPD3 exhibited superior antitumor efficacy in CDX models compared with benchmark mono-targeting ADCs with TopoI payloads, even those using the same CPD3. Furthermore, we generated a dual-payloads ADC, DR319-DP, with a DAR of 4 TopoI + 2 microtubule inhibitor (MTI), through a one-step glyco-conjugation strategy. This construct is designed to deliver synergistic, orthogonal mechanisms of action (MOA) to address tumor heterogeneity and therapeutic resistance. In our studies, DR319-DP demonstrated excellent target and bystander killing and achieved more potent and durable tumor suppression than mono-targeting ADCs (with either TopoI or MTI payloads) and DR319-CPD3, across multiple CDX and PDX models. Additionally, our characterization confirmed that DR319-DP displayed excellent thermal and plasma stability, along with a favorable pharmacokinetic (PK) profile in mice and cynomolgus monkeys. DR319 is precision-engineered with an avidity-driven backbone to minimize the on-target toxicities that limit current Nectin-4 and Trop-2 therapies. The incorporation of synergistic dual-MOA payloads (DP) into DR319 provides a comprehensive strategy to maximize efficacy and overcome resistance. These preclinical data strongly support the clinical development of DR319 ADCs as a potential best-in-class therapeutic for solid tumors.", "source_company": "Zhejiang Doer Biologics Co., Ltd", "source_org_type": "公司", "row_number": 163, "target_meta": "NECTIN4,TROP2", "MOA_meta": "抗体偶联药物"}, {"drug_name": "SC3499", "company": "Dong-A ST Co. Ltd", "org_type": "公司", "target": "EGFR (mutant, allosteric degrader)", "modality": "degrader", "importance_level": "高", "total_score": 76.5, "institution_score": 65, "track_score": 90, "milestone_score": 70, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "SC3499为口服allosteric EGFR degrader，针对L858R突变型EGFR并克服osimertinib耐药，包括C797S等复合突变，机制新颖且preclinical数据强劲。机构为韩国本土领先药企，靶点EGFR+PROTAC-like degrader赛道热度高，综合潜力显著。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8705", "id": "C1XM_5wBX1NQZOEH-LO6", "source_drug_name": "SC3499", "title": "Rationally designed allosteric EGFR degrader SC3499 (IN-207375) selectively eliminates mutant EGFR and overcomes osimertinib resistance in non-small cell lung cancer", "abstract_text": "Epidermal growth factor receptor (EGFR) tyrosine kinase inhibitors (TKIs) have demonstrated remarkable therapeutic efficacy in patients with non-small cell lung cancer (NSCLC) harboring activating EGFR mutations. However, acquired resistance often driven by secondary EGFR mutations remains a major clinical challenge. Although the third-generation covalent inhibitor osimertinib effectively overcomes T790M-mediated resistance and is widely used as first-line therapy. Nevertheless, resistance to osimertinib eventually develops, and patients with the EGFR L858R mutation often experience less durable responses than those with exon 19 deletions. Therapeutic options for patients who progress after osimertinib remain limited. Targeted protein degraders act through a catalytic, event-driven mechanism that can reduce on-target resistance relative to occupancy-driven inhibitors. SC3499 is an orally active, allosteric bifunctional degrader rationally designed to selectively target mutant EGFR containing the oncogenic L858R mutation. In preclinical studies, SC3499 demonstrated potent and durable antitumor activity in both in vitro and in vivo L858R-driven NSCLC models. Importantly, SC3499 maintained full activity against multiple resistance mutations, including L858R/C797S, L858R/T790M, and L858R/T790M/C797S, which confer resistance to approved EGFR TKIs such as osimertinib. In in vivo studies, SC3499 exhibited favorable pharmacokinetic properties, excellent oral bioavailability, and induced marked tumor regression with once-daily oral dosing. Broad kinase profiling showed exceptional kinase selectivity, and global proteomic analysis confirmed selective degradation of mutant EGFR without affecting unrelated proteins or other cereblon (CRBN) substrates. These results support SC3499 as a promising, orally active, allosteric EGFR degrader capable of overcoming resistance to current EGFR-targeted therapies, including osimertinib, and providing durable antitumor responses in EGFR-mutant NSCLC.", "source_company": "Dong-A ST Co. Ltd", "source_org_type": "公司", "row_number": 232, "target_meta": "EGFR", "MOA_meta": "降解剂"}, {"drug_name": "FHT-171", "company": "Foghorn Therapeutics", "org_type": "公司", "target": "CBP", "modality": "degrader", "importance_level": "高", "total_score": 76.5, "institution_score": 75, "track_score": 90, "milestone_score": 60, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "FHT-171为首创选择性CBP降解剂，针对CBP依赖性实体瘤尤其是EP300突变肿瘤，利用合成致死机制。Foghorn为专注染色质调控的临床阶段biotech公司，靶向蛋白降解赛道热度高，preclinical数据全面但尚未进入临床，总分较高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8694", "id": "NlXM_5wBX1NQZOEH-LO6", "source_drug_name": "FHT-171", "title": "Preclinical characterization of FHT-171, a first-in-class degrader targeting CREB-binding protein (CBP) in CBP-dependent solid tumors", "abstract_text": "The paralog lysine acetyltransferases CREB-binding protein (CBP) and E1A-binding protein P300 (EP300) function as transcriptional coactivators that regulate diverse cellular programs. Functional screens have revealed a bidirectional synthetic relationship between these two paralogs in tumor cell biology. This synthetic lethal relationship offers a therapeutic opportunity in selectively targeting CBP in EP300-mutant as well as other CBP-dependent cancers. Herein, we present a comprehensive preclinical evaluation for a first-in-class, selective CBP degrader, FHT-171, designed to target transcriptional co-activator dependencies in solid tumors. Through a series of in vitro and in vivo studies, we characterize the compound’s biochemical selectivity, cellular degradation kinetics, transcriptional impacts, antitumor efficacy and tolerability across multiple solid tumor models. These findings provide mechanistic and non-clinical translational insight into the therapeutic potential of CBP degradation and support further development of this novel modality for the treatment of CBP-dependent malignancies.", "source_company": "Foghorn Therapeutics", "source_org_type": "公司", "row_number": 234, "target_meta": "CBP", "MOA_meta": "降解剂"}, {"drug_name": "A-911", "company": "AbbVie Inc.", "org_type": "公司", "target": "5-HT7", "modality": "inhibitor", "importance_level": "高", "total_score": 76.5, "institution_score": 95, "track_score": 75, "milestone_score": 40, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "A-911为AbbVie开发的口服生物可用5-HT7受体拮抗剂（antagonist/inhibitor），通过促进DC1介导的T细胞交叉启动增强抗肿瘤免疫。机构为头部MNC得分高，但因摘要禁运仅处于发现阶段preclinical且靶点5-HT7在肿瘤免疫领域非主流热门，得分中等偏上，总分达高重要性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11536", "id": "_FXM_5wBX1NQZOEH-LO6", "source_drug_name": "A-911", "title": "Discovery of A-911, a potent, orally bioavailable 5-HT7 antagonist that promotes DC1-mediated T-cell cross-priming and anti-tumor immunity", "abstract_text": "Abstract is embargoed at this time.", "source_company": "AbbVie Inc.", "source_org_type": "公司", "row_number": 249, "target_meta": "HTR7", "MOA_meta": "抑制剂"}, {"drug_name": "ATL-024", "company": "Antelope Therapeutics", "org_type": "公司", "target": "CA242 (CanAg)", "modality": "ADC", "importance_level": "高", "total_score": 76.5, "institution_score": 65, "track_score": 90, "milestone_score": 75, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "ATL-024为靶向肿瘤特异性糖肽表位CA242的拓扑异构酶I类ADC，在结直肠癌和胰腺癌PDX模型中显示强效抗瘤活性，安全性良好。公司由ADC领域资深专家创立（前Mablink高管），处于IND-enabling阶段，赛道为热门ADC+exatecan payload，靶点在GI肿瘤中具特异性且此前临床验证安全。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4446", "id": "TFXM_5wBX1NQZOEH-LS6", "source_drug_name": "ATL-024", "title": "ATL-024, a novel topoisomerase I-based ADC targeting the tumor-specific glycopepitope CA242 (CanAg), demonstrates potent activity in colorectal and pancreatic cancer models, and excellent safety profile", "abstract_text": "CA242 (also known as CanAg) is a tumor-associated carbohydrate antigen that is aberrantly expressed by gastrointestinal solid tumors but is virtually absent from normal tissue. In particular, this glycopepitope is highly expressed in colorectal, pancreatic and gastric tumors (high prevalence and elevated number of copies per tumor cell). Previous clinical trials in the early 2000s showed that CA242 can be safely targeted with an antibody-drug conjugate (ADC), as no significant CA242-related off-tumor toxicities were reported. The modest clinical benefit seen with microtubule inhibitor payloads indicates that alternative payloads, such as topoisomerase-I inhibitors, may enhance therapeutic outcomes in CA242-positive tumors.To exploit CA242 differential expression, we developed a novel CA242-targeting ADC called ATL-024, which is comprised of an anti-CA242 humanized Fc-silenced monoclonal antibody conjugated to the topoisomerase I inhibitor exatecan via a dipeptide cleavable linker. This ADC is a homogeneous construct with a drug-to-antibody ratio (DAR) of 4.ATL-024 demonstrated potent antitumor efficacy in multiple colorectal and pancreatic cancer PDX models showing homogeneous or heterogeneous CA242 expression patterns (as determined by IHC), being effective at doses as low as 3-6mg/kg. Compared to previous cantuzumab-DM4 based ADC (microtubule inhibitor payload), ATL-024 exhibits significantly stronger in vivo anti-tumor activity in colorectal PDX models.In a pilot toxicology study in cynomolgus monkeys, ATL-024 was well tolerated up to 80 mg/kg (Q3W), which was established as the highest non-severely toxic dose (HNSTD). At this dose, findings were limited to mild and reversible hematologic changes in one animal, with normal clinical chemistry parameters, no severe clinical signs and no observed organ toxicities. Pharmacokinetic profiling showed linear dose-dependent exposure and is consistent with systemic stability of the conjugate.Overall, the preclinical characterization of ATL-024 shows a very favorable therapeutic index and support human clinical evaluation for patients with CA242-expressing gastrointestinal tumors such as colorectal or pancreatic tumors. ATL-024 is currently undergoing IND-enabling development.", "source_company": "Antelope Therapeutics", "source_org_type": "公司", "row_number": 254, "target_meta": "CA242", "MOA_meta": "抗体偶联药物"}, {"drug_name": "CT7311", "company": "Carrick Therapeutics", "org_type": "biotech", "target": "cyclin K-CDK12", "modality": "degrader", "importance_level": "高", "total_score": 76.5, "institution_score": 75, "track_score": 85, "milestone_score": 65, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "CT7311为Carrick Therapeutics的cyclin K蛋白降解剂，靶向cyclin K-CDK12复合物，通过限制RPA染色质加载诱导复制应激，与ATR抑制剂协同显著增强TNBC疗效。机构为国外头部biotech且赛道为热门degrader+新型DNA损伤机制，preclinical机制深入且具协同潜力，得分较高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4637", "id": "jFXM_5wBX1NQZOEH-LS6", "source_drug_name": "CT7311", "title": "Targeting cyclin K-CDK12 synergizes with ATR inhibition by limiting RPA chromatin loading in triple-negative breast cancer", "abstract_text": "Targeting cyclin K-CDK12 is a promising therapeutic due to its ability to induce homologous recombination (HR) repair deficiency through transcriptional regulation. Reduced CDK12 activity sensitizes HR repair-proficient tumor cells to PARP inhibitors (PARPi) and DNA-damaging agents. However, recent studies show that CDK12-mutant cancers lack the genomic signatures associated with HR repair deficiency and derive limited therapeutic benefit from PARPi. It is therefore essential to understand additional mechanisms by which cyclin K-CDK12 depletion promotes genomic instability beyond impaired HR repair. Here, we demonstrate that cyclin K-CDK12 depletion drives a replication stress (RS)-associated vulnerability and synergizes with ATR inhibition, using CT7311 (Carrick Therapeutics), a protein degrader of cyclin K. Triple-negative breast cancer (TNBC) cells, especially those with high MYC expression, were the most sensitive to CT7311 compared with estrogen receptor-positive (ER+) BC and non-transformed breast cells. Notably, CT7311 sensitivity did not correlate with HR repair status. In a DNA damage response-focused CRISPR screen with CT7311, DNA replication-related genes were highly enriched among the sensitizers, with effects stronger than those of HR repair-related factors. We validated three sensitizers, TOPBP1, PRIM2, and PRPF19, which are closely linked to ATR activation, a central RS regulator. Consistent with the screen, cyclin K-CDK12 depletion yielded synergistic cytotoxicity with ATR inhibition only in TNBC, not in ER+ BC cells. Mechanistically, CT7311 induces transcription-replication conflicts (TRCs), a known RS source, but fails to robustly activate ATR. Rather, it limits ATR activation by reducing the chromatin loading of Replication Protein A (RPA). This impaired ATR activation is further exacerbated when combined with tuvusertib (ATRi), leading to marked DNA damage specifically in replicating cells. Strikingly, RPA overexpression conferred resistance to the combination, indicating that the synergy arises from impaired availability of RPA. We further show that cyclin K-CDK12 regulates RPA chromatin loading via the PRPF19 E3-ligase complex. AlphaFold-Multimer predictions revealed interactions between cyclin K-CDK12 and the PRPF19 complex. CT7311 disrupted PRPF19 complex assembly, compromising its activity and impairing RPA ubiquitination. Notably, CDK12-mediated phosphorylation of CDC5L, a PRPF19 complex subunit, was required for RPA chromatin loading. Collectively, our work identifies cyclin K-CDK12 as a critical regulator of RPA dynamics and uncovers ATR dependency driven by cyclin K-CDK12 depletion. These insights extend the rationale for cyclin K-CDK12 targeted therapy beyond HR repair-focused applications, supporting its use in RS-high tumors including TNBC, as monotherapy or in combination with ATR inhibition.", "source_company": "Dana-Farber Cancer Institute", "source_org_type": "医院", "row_number": 257, "target_meta": "CDK12", "MOA_meta": "降解剂"}, {"drug_name": "TRO-02", "company": "TriOar Inc.", "org_type": "公司", "target": "EGFR", "modality": "ADC", "importance_level": "高", "total_score": 76.5, "institution_score": 65, "track_score": 90, "milestone_score": 75, "field_heat_score": 85, "bonus_score": 3, "brief_reason": "TRO-02为条件激活型EGFR靶向ADC，采用TROCADTM masking平台和TROSIGTM linker，实现肿瘤微环境特异激活并增强肿瘤递送，显著改善治疗窗；TriOar作为专注ADC平台的韩国新兴biotech虽非头部但获Celltrion大额合作，赛道热门且展示强效PDX数据及良好PK，综合潜力较高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4383", "id": "kZ7M_5wBZznHJdnt_W7P", "source_drug_name": "TRO-02", "title": "TRO-02, a conditionally activated EGFR-targeting ADC incorporating TROCADTM and TROSIGTM platforms, shows enhanced tumor selectivity and potent efficacy", "abstract_text": "Epidermal growth factor receptor (EGFR) represents a validated therapeutic target across multiple solid tumor indications, including non-small cell lung cancer, head and neck squamous cell carcinoma, and colorectal cancer. However, EGFR expression in normal epithelial tissues, particularly skin, has limited the therapeutic window of EGFR-targeted therapies, often causing dose-limiting toxicities that impair clinical efficacy. To overcome this challenge, we developed TRO-02, a novel conditionally activated EGFR-targeting antibody-drug conjugate (ADC) that selectively activates in the tumor microenvironment while remaining masked in healthy tissues. TRO-02 is a DAR8-type ADC generated by conjugating a potent topoisomerase I inhibitor to panitumumab via a cleavable, stable, and hydrophilic TROSIGTM linker. Furthermore, it incorporates our proprietary TROCADTM platform, which provides dual functions: (1) masking the panitumumab to prevent EGFR binding until proteolytic cleavage by tumor-associated proteases, and (2) guiding the ADC to the tumors by targeting annexin A1, which is highly expressed on tumor vasculature and facilitates transcytosis. This dual mechanism allows TRO-02 achieve both specific activation within the tumor microenvironment and selective tumor delivery. In vitro, the masked TRO-02 exhibited approximately 100-fold weaker binding to EGFR than the activated ADC, confirming effective suppression of target engagement. The unmasked TRO-02 displayed sub-nanomolar cytotoxicity against EGFR-expressing tumor cells, whereas the masked form showed markedly reduced cytotoxicity, with 30- to 100-fold lower potency depending on the cell type compared with the unmasked form. In MDA-MB-231 xenograft model, a single dose of 0.3 and 1 mg/kg achieved 65% and 98 % tumor growth inhibition, respectively. Rat plasma stability studies showed high stability, with >85% of intact ADC remaining after 7 days of incubation. Furthermore, pharmacokinetic analysis in rats demonstrated favorable PK properties (t1/2 = 4.47 days, AUC = 163.52 day·μg/mL, CL = 25.05 mL/day/kg, Vd = 0.08 L/kg at 4 mg/kg), indicating high in vivo stability and low clearance. Collectively, these findings demonstrate that TRO-02 is a conditionally activated EGFR-targeting ADC with improved therapeutic index, achieving potent antitumor efficacy while minimizing on-target/off-tumor toxicity.", "source_company": "TriOar Inc.", "source_org_type": "公司", "row_number": 280, "target_meta": "EGFR", "MOA_meta": "抗体偶联药物"}, {"drug_name": "RetroT all-RNA genome integration platform", "company": "CREATE Medicines", "org_type": "公司", "target": "未披露", "modality": "other", "importance_level": "高", "total_score": 76.5, "institution_score": 75, "track_score": 90, "milestone_score": 60, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "RetroT为全RNA基因整合平台，利用LINE-1实现T细胞体内位点特异性耐久CAR整合，新机制安全性高。机构为临床阶段biotech，赛道热门（RNA+体内CAR工程），preclinical数据支持但摘要禁运，综合潜力强。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11534", "id": "RVXM_5wBX1NQZOEH-LG5", "source_drug_name": "RetroT all-RNA genome integration platform", "title": "Durable anti-tumor immunity through in vivo CAR T cell engineering using the RetroT all-RNA genome integration platform", "abstract_text": "Abstract is embargoed at this time.", "source_company": "CREATE Medicines", "source_org_type": "公司", "row_number": 357, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "PRMT5-directed degraders", "company": "SK Life Science Labs", "org_type": "公司", "target": "PRMT5", "modality": "degrader", "importance_level": "高", "total_score": 76.5, "institution_score": 75, "track_score": 90, "milestone_score": 60, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "靶向PRMT5的degrader通过泛素蛋白酶体系统实现快速、选择性降解，可克服传统PRMT5抑制剂的剂量限制和不完全靶点覆盖，机制新颖。SK Life Science Labs作为SK Biopharmaceuticals子公司属于国外biotech，TPD+PRMT5赛道热度高，但仍处preclinical阶段。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8743", "id": "r1XM_5wBX1NQZOEH-LO6", "source_drug_name": "PRMT5-directed degraders", "title": "Next-generation PRMT5 activity modulation through directed degradation", "abstract_text": "PRMT5 is a key epigenetic regulator that is responsible for symmetric demethylation (SDMA) of arginine residues on histones and non-histone proteins, leading to regulation of transcription, RNA splicing, and genome stability. PRMT5 activity is linked to a range of malignancies, making it an attractive therapeutic target. The therapeutic potential of SAM and protein substrate competitive PRMT5 inhibitors have been hampered by dose-limiting cytopenia leading to incomplete target coverage. In contrast, MTA-cooperative inhibitors exploit the accumulation of MTA, a SAM-competitive inhibitor of PRMT5, in MTAP-deleted tumors to achieve enhanced tumor selectivity. MTA-cooperative degraders offer the potential to eliminate both catalytic and non-catalytic functions of PRMT5 with improved depth and durability of target modulation. Here, we describe PRMT5-directed degraders that rapidly, potently, and selectively eliminate PRMT5. Our degraders exhibit potent and robust PRMT5 degradation within 6 hours of treatment, leading to marked suppression of SDMA. Mechanistic studies demonstrate that PRMT5 loss is strictly dependent on UPS, as pharmacological blockade of ubiquitination or proteasomal activity effectively abrogates degrader-induced PRMT5 turnover. Our data highlights the potential for PRMT5 targeted degradation, driving a rapid and selective silencing of PRMT5 activity that can overcome limitations of first-generation inhibitors and provide a differentiated therapeutic approach for PRMT5-driven cancers.", "source_company": "SK Life Science Labs", "source_org_type": "公司", "row_number": 770, "target_meta": "PRMT5", "MOA_meta": "降解剂"}, {"drug_name": "ONCO Prime", "company": "Ryvu Therapeutics", "org_type": "公司", "target": "未披露", "modality": "other", "importance_level": "高", "total_score": 76.5, "institution_score": 75, "track_score": 85, "milestone_score": 65, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "ONCO Prime为Ryvu Therapeutics的专有合成致死靶点发现平台，聚焦KRAS等驱动突变CRC的精准治疗新靶点，但未披露具体药物靶点。Ryvu作为欧洲临床阶段biotech机构实力较强，合成致死赛道热度高，平台已实现POC并有FDA批准药验证，整体潜力显著。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4670", "id": "1lXM_5wBX1NQZOEH-LO6", "source_drug_name": "ONCO Prime", "title": "ONCO Prime platform enables discovery of synthetic lethal targets for genetically stratified cancers", "abstract_text": "Colorectal cancer (CRC) remains a leading cause of cancer mortality, underscoring the need for new, mechanism-based therapeutic strategies. Using the ONCO Prime discovery and validation platform, based on genome wide CRISPR/Cas9 screenings across clinically relevant models, we identified novel treatment options for genetically stratified CRC patients The ONCO Prime platform integrates healthy human intestinal stem cells (hISCs), isogenic CRC models carrying key driver mutations (APC, KRAS), and patient-derived primary cultures. All types of models can be genetically manipulated or used in the high-throughput setting for the drug testing. Transcriptomic and machine learning analyses confirmed that these models faithfully recapitulate CRC molecular diversity and clinical behavior. Systematic CRISPR/Cas9 loss-of-function screenings revealed multiple synthetic lethal (SL) interactions, uncovering target genes with first-in-class therapeutic potential. Additionally, using a clinical grade drug that is FDA-approved in other indications, we achieved proof of concept in genetically stratified CRC models, demonstrating strong efficacy as monotherapy in vitro. These data validate ONCO Prime’s translational capability to uncover clinically actionable vulnerabilities and deliver tangible therapeutic candidates. This work provides a robust foundation for drug discovery programs and strategic partnerships built on ONCO Prime’s ability to bridge functional genomics with therapeutic development. Our first proof of concept establishes ONCO Prime as a scalable platform to drive the next generation of precision, first-in-class oncology therapies.", "source_company": "Ryvu Therapeutics", "source_org_type": "公司", "row_number": 801, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "FX-909", "company": "Flare Therapeutics", "org_type": "公司", "target": "PPARG", "modality": "inhibitor", "importance_level": "高", "total_score": 76.5, "institution_score": 75, "track_score": 85, "milestone_score": 70, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "FX-909为首创PPARG（转录因子）逆向激动剂/抑制剂，针对难成药靶点，在尿路上皮癌中显示单药活性及与anti-PD-1协同免疫调制潜力。Flare Therapeutics为专注转录因子的临床阶段biotech，赛道新颖且具FIC价值，早期临床里程碑支持较高综合重要性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/12036", "id": "IFXM_5wBX1NQZOEH-LS6", "source_drug_name": "anti-PD-1", "title": "Phase 0 intratumoral microdevice study of FX-909 in bladder cancer demonstrates on-target anti-tumor activity and immune modulation, enhanced in combination with anti-PD-1", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Flare Therapeutics", "source_org_type": "公司", "row_number": 852, "target_meta": "PPARγ", "MOA_meta": "抑制剂"}, {"drug_name": "lead compounds", "company": "Peptone Switzerland AG / Peptone Ltd.", "org_type": "公司", "target": "AR N-terminal domain", "modality": "inhibitor", "importance_level": "高", "total_score": 76.5, "institution_score": 75, "track_score": 85, "milestone_score": 65, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "靶向AR NTD的小分子抑制剂，针对CRPC抵抗机制提供新型机制，通过in silico和HDX-MS等平台发现，体外活性10-100 nM并优于enzalutamide。Peptone为国外头部biotech（Series A 4000万美元融资），赛道为热门难成药靶点+小分子抑制剂，preclinical强度较高但尚未临床。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6412", "id": "mVXM_5wBX1NQZOEH-LS6", "source_drug_name": "lead compounds", "title": "In silico discovery of potent small molecule inhibitors targeting the AR N-terminal domain for treating castration-resistant prostate cancer", "abstract_text": "Castration-resistant prostate cancer (CRPC) remains an unsolved clinical challenge due to resistance mechanisms that occur upon treatment with androgen receptor pathway inhibitors (ARPI). Since the hallmarks of resistance are (i) AR amplification, (ii) the occurrence of splice variants like AR-V7 and (iii) mutations in the ligand binding domain (LBD), the novel concept of targeting the disordered N-terminal domain (NTD) of the androgen receptor is a compelling way of inhibiting AR in the context of castration-resistance. Here, we describe the discovery of small-molecule AR-NTD inhibitors by leveraging Peptone’s HDX-MS and in silico platform. A virtual screen against a highly dynamic segment of the NTD yielded binders that were further developed into a series with potent in vivo activity. Binding was confirmed by multiple biophysical approaches, including a proprietary ultra-fast mixing hydrogen-deuterium exchange mass spectrometry (HDX-MS), NMR spectroscopy, spectral shift analysis, and cellular NanoBit assays, all of which validated direct interaction with the NTD. Our lead compounds exhibit potent cellular activity across a range of in vitro models. In AR full-length (FL-AR) and AR-V7 luciferase reporter assays, as well as LNCaP proliferation assays, potencies between 10-100 nM were obtained. Activity in the VCaP CRPC cell model was similarly strong, clearly outperforming standard-of-care compounds like Enzalutamide and Darolutamide and reaching equal potency to PROTACs. Mode of action (MoA) studies demonstrated that the lead compounds suppress the formation of FL-AR and AR-V7 homodimers (NanoBit assay), inhibit nuclear translocation of AR, and can efficiently downregulate AR-target genes in a dose-dependent manner in qPCR assays. The lead series displays drug-like physicochemical, ADME, and pharmacokinetic profiles, conducive to rapid preclinical and clinical development, while providing distinct differentiation over novel modalities such as PROTACs and RIPTACs. Our findings highlight the therapeutic promise of targeting the AR-NTD in CRPC via a unique, structure-driven approach, with small molecules that combine a novel mechanism with potent anti-tumor activity.", "source_company": "Peptone Switzerland AG\nPeptone Ltd.", "source_org_type": "公司", "row_number": 942, "target_meta": "not available", "MOA_meta": "抑制剂"}, {"drug_name": "p53 restoration therapy", "company": "Hanmi Pharm. Co. Ltd.", "org_type": "公司", "target": "p53", "modality": "mRNA", "importance_level": "高", "total_score": 76.5, "institution_score": 75, "track_score": 90, "milestone_score": 60, "field_heat_score": 85, "bonus_score": 3, "brief_reason": "该疗法通过mRNA平台恢复p53肿瘤抑制功能，针对TP53突变癌症，具有新机制和较高临床潜力。Hanmi作为韩国头部pharma在热门mRNA+肿瘤抑制基因赛道布局积极，但仍处preclinical阶段且为预测模型研究。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3015", "id": "nZ7M_5wBZznHJdnt_W3O", "source_drug_name": "p53 restoration therapy", "title": "A transcriptomic framework to predict response and prioritize indications for p53 restoration therapy", "abstract_text": "Introduction: TP53 has been recognized as a promising therapeutic target because of its pivotal role in tumor suppression and the high prevalence of its functional alterations in cancer. However, sensitivity to p53 restoration varies markedly across cancer cell lines and is not determined solely by the presence or absence of intact p53. These findings suggest that additional, pathway-level factors may modulate responsiveness to p53 reactivation. In this study, focusing on p53 restoration therapy, we aimed to (1) elucidate molecular mechanism underlying variable responses, (2) build a transcriptomic prediction model capable of estimating restoration sensitivity, and (3) apply this framework to prioritize clinical indications across tumor types.\nMethods: In vitro results of p53 restoration were curated from 28 cell lines (20 sensitive [S], 8 resistant [R]). Transcriptomic differences between S and R were evaluated by Gene set enrichment analysis (GSEA) and gene set variation analysis (GSVA) using p53-related gene sets from MSigDB. RNA expression data were normalized by Non-paranormal (NPN) transformation, and singscore values were computed to quantify pathway activity. A logistic regression model was trained to estimate the probability of S or R classification, with the cutoff (specificity ≥0.9) stabilized through bootstrap resampling and fixed at the median. External datasets - CCLE, TCGA, cBioPortal, and GEO (GSE271757, GSE223463, GSE169321) - were analyzed to explore appropriate clinical indications.\nResults: GSEA revealed a distinct downregulation of DNA elongation and Mismatch repair pathways in the S group, indicating reduced baseline DNA repair activity in S cells. Among gene sets tested, Signature A, achieved the strongest discriminatory power between S and R (PR AUC = 0.754). For indication prioritization, integrative analysis combining Signature A-based predictions from CCLE and TCGA, together with TP53 alteration prevalence from cBioPortal, identified lung, head and neck, ovarian cancers as Tier 1 indications. By investigating the biological nature of Signature A, we observed that DNA-damaging therapies may enhance p53 restoration sensitivity. Consistently, analysis of GEO cohorts with pre- and post-treatment RNA-seq data revealed an increased fraction of S from 52% to 96% in ovarian cancer, and 85% to 92% in pancreatic cancer following DNA-damaging therapy.\nConclusion: Signature A, a transcriptomic signature, stratifies p53 restoration responsiveness across cancer types and provides a robust, reproducible framework for indication prioritization and for understanding the mechanistic context of p53 restoration during the patient treatment journey.", "source_company": "Hanmi Pharm. Co. Ltd.", "source_org_type": "公司", "row_number": 1057, "target_meta": "p53", "MOA_meta": "其他"}, {"drug_name": "Nanoprimer", "company": "Nanobiotix", "org_type": "公司", "target": "未披露", "modality": "other", "importance_level": "高", "total_score": 76.5, "institution_score": 75, "track_score": 85, "milestone_score": 65, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "Nanoprimer是一种脂质体纳米颗粒技术，用于暂时占据单核吞噬细胞系统以提升静脉给药疫苗（如mRNA和肽疫苗）的生物利用度，增强癌症疫苗的CD8+ T细胞免疫应答。公司为纳斯达克上市的临床阶段biotech，市值约14-15亿美元，preclinical数据显示显著提升急性和记忆免疫反应，具有平台化赋能多种IV疗法的潜力。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6405", "id": "sJ7M_5wBZznHJdnt_W3O", "source_drug_name": "Nanoprimer", "title": "Nanoprimer technology for enhanced efficacy of intravenously administered vaccines", "abstract_text": "The efficacy of intravenously (IV) administered therapeutic agents is often limited by hepatic clearance, resulting in reduced accumulation at the target site and in potential hepatotoxicity. Nanobiotix’s innovative Nanoprimer technology aims to shift the balance of therapeutics’ bioavailability and toxicity. The Nanoprimer is a biocompatible, engineered liposome that transiently occupies cells of the mononuclear phagocyte system, responsible for the clearance of nanoparticles. Administered shortly before the therapeutic agent, the Nanoprimer reduces the early elimination and increases bioavailability during the agent’s critical window of activity. proofs of concept were realized with multiple modalities including nucleic acid-based products. Our latest research has expanded the evaluation of the Nanoprimer for enhancing the efficacy of cancer vaccines. The Nanoprimer’s effect on antigen-specific CD8⁺ T cell responses was evaluated using 2 vaccine platforms: mRNA-loaded lipoplex encoding an ovalbumin epitope and ovalbumin peptide-loaded liposomes. De novo priming of CD8⁺ T cells was assessed 7 days post-immunization. To evaluate the functional activity of generated CD8⁺ T cells, splenocytes were restimulated ex vivo with the antigenic peptide for 24 hours, and IFN-γ production was quantified. In a single-dose immunization study, using peptide-loaded liposomes, pre-treatment with the Nanoprimer resulted in a 6-fold increase in antigen-specific CD8⁺ T cells and a marked elevation of IFN-γ production by splenocytes, indicative of a strong effector function. Similar studies using a single dose of mRNA-lipoplex demonstrated that the Nanoprimer dramatically enhanced the generation of antigen-specific CD8⁺ T cells, reaching up to 20% of the total CD8⁺ T cells. The expansion of antigen-specific CD8⁺ T cells was correlated with increased IFN-γ secretion, consistent with functional cytotoxic activity. For the evaluation of the memory immune response, animals received a primary vaccination (three repeated injections of the vaccine at days 0, 7 and 14), and memory response was assessed on day 73 by measuring the frequency of antigen-specific CD8+ T cells, 3 days after the booster immunization. The Nanoprimer increased antigen-specific CD8+ T cell responses, reaching up to 54% of total CD8+ T cells for mRNA-lipoplex (compared to 27% with vaccine alone) and up to 27% for peptide-liposome (with no detectable response observed in the vaccine alone group). These findings demonstrate that the Nanoprimer can enhance acute and memory cellular immune responses across multiple vaccine modalities. Its ability to increase antigen-specific CD8⁺ T cell quantities and functional cytokine responses underscores its potential to improve the therapeutic index of cancer immunotherapies. Overall, Nanoprimer technology represents a promising strategy to unlock the full clinical potential of innovative therapies.", "source_company": "Nanobiotix", "source_org_type": "公司", "row_number": 1072, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "bispecific T cell engager prodrug targeting ENPP3", "company": "Probio, Inc", "org_type": "公司", "target": "ENPP3", "modality": "bispecific T cell engager prodrug", "importance_level": "高", "total_score": 76.5, "institution_score": 65, "track_score": 85, "milestone_score": 80, "field_heat_score": 75, "bonus_score": 5, "brief_reason": "靶点ENPP3为肾细胞癌等实体瘤相关抗原，具有良好肿瘤选择性；采用prodrug masked TCE设计显著提升安全性（剂量提高100倍无毒性），in vitro/in vivo验证有效性强。机构为GenScript子公司Probio，全球CDMO背景较强但非头部原研药企，热门TCE+条件激活机制+新兴靶点综合热度高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5512", "id": "vp7M_5wBZznHJdnt_W3O", "source_drug_name": "bispecific T cell engager prodrug targeting ENPP3", "title": "The discovery and development of a bispecific T cell engager prodrug targeting ENPP3", "abstract_text": "T cell engager (TCE) antibodies have been proven to be effective for a variety of hematological malignancies, with at least 10 marketed drugs to date; however, their efficacy in many solid tumors is still very limited due to a number of challenges. One of the leading challenges is the lack of tumor-specific targets, leading to an increased risk of on-target, off-tumor toxicity. An approach to address this challenge is to build a “prodrug” TCE that is conditionally activated in the tumor microenvironment (TME), taking advantages of various masking technology platforms that block the release of active TCE drug outside of the TME. To develop such a novel TCE molecule with improved tumor selectivity, potency, and safety profile, we first discovered a masking peptide specific to a CD3 VHH antibody that we previously developed, and demonstrated that the masked CD3 VHH can effectively reduce T cell activation several hundred-fold. Next, we fused this masking peptide to the CD3 VHH arm via a proteolytically-labile linker containing sequence motifs sensitive to proteases enriched in the TME, and showed that upon cleavage by proteases, the T cell-activating potency of such a masked CD3 VHH can be effectively recovered. Finally, with such a CD3 VHH armed with cleavable linker and masking peptide, we built a series of prodrug TCE molecules targeting ENPP3 (ectonucleotide pyrophosphatase/phosphodiesterase family member 3), a tumor associated antigen with good tumor selectivity for renal cell carcinoma. Our in vitro validation studies demonstrated that the potency of these TCE prodrugs in killing ENPP3+ tumor cells can be restored to a similar level as the unmasked, active TCE molecule upon proteolytic cleavage. Our in vivo studies using an ENPP3+ CDX model with transplanted human PBMCs demonstrated two important points: (i) the prodrug/masked ENPP3-targeted TCE can potently inhibit tumor growth to a comparable level as the unmasked version and clinical benchmarks, and (ii) the prodrug TCE can be dosed at least 100-fold higher than the active drugs without any observed toxicity, suggesting a greatly improved safety profile. Further preclinical development of these ENPP3-targeted prodrug TCE molecules, including pharmacokinetics and toxicity studies in non-human primates, is ongoing.", "source_company": "Probio, Inc", "source_org_type": "公司", "row_number": 1087, "target_meta": "ENPP3", "MOA_meta": "其他"}, {"drug_name": "GDF-15-neutralizing antibody", "company": "CatalYm GmbH", "org_type": "公司", "target": "GDF-15", "modality": "inhibitor", "importance_level": "高", "total_score": 76.5, "institution_score": 75, "track_score": 85, "milestone_score": 70, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "靶点GDF-15为肿瘤免疫逃逸和化疗抵抗关键介质，中和抗体可恢复CD8+ T细胞浸润并改善化疗免疫联合疗效。CatalYm为专注IO的欧洲临床阶段biotech，已推进至Phase 2b，preclinical数据展示明确协同价值和毒性改善。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1340", "id": "ep7M_5wBZznHJdnt_W7P", "source_drug_name": "GDF-15-neutralizing antibody", "title": "GDF-15 inhibition overcomes treatment resistance to platinum- and taxane-based cytotoxic chemoimmunotherapy", "abstract_text": "Background: GDF-15 is a stress-induced cytokine that restricts CD8+ T cell infiltration, drives immunotherapy resistance, and mediates chemotherapy-induced nausea, emesis, anorexia, and cancer cachexia. Durable responses to GDF-15 blockade have been reported in PD-1-refractory NSCLC and UC, supporting its role as a clinically relevant mediator of immune escape. Because platinum agents and other DNA-damage-inducing therapies strongly upregulate GDF-15, we investigated whether therapy-induced GDF-15 limits the antitumor activity and tolerability of combined PD-1 blockade and cytotoxic chemotherapy.\nMethods: Human tumor cell lines were treated with platinum compounds, docetaxel, and a panel of DNA-damage inducers, DNA-damage-repair inhibitors, and cell-cycle and transcriptional stress-inducing agents, and GDF-15 secretion was quantified. Syngeneic MBT-2 and MC-38 models received cisplatin or docetaxel plus anti-PD-1, with or without a GDF-15-neutralizing antibody. Tumor growth, survival, body weight, serum GDF-15, intratumoral immune populations, and peripheral CD8+ T cell activation were analyzed by ELISA, flow cytometry, bulk RNA sequencing, and single-cell RNA sequencing.\nResults: A broad range of DNA-damage-inducing, DNA-damage-repair-inhibitory, and cell-cycle stress-inducing agents robustly induced GDF-15 in vitro. In vivo, cisplatin plus anti-PD-1 markedly increased systemic GDF-15 but yielded limited tumor control. Adding GDF-15 blockade substantially delayed tumor growth, extended survival, and fully prevented cisplatin-associated weight loss. Single-cell RNA sequencing demonstrated increased intratumoral CD8+ T cell infiltration. scRNA-seq and bulk RNA sequencing together showed enrichment of activation, co-stimulation, cytotoxicity, and TCR-signaling programs (Lck, Fyn, Zap70, Lat; Gzmb, Prf1; CCL5). Flow cytometry confirmed increased peripheral CD8+ T cell proliferation (Ki67+) and a higher proportion of activated effector CD8+ T cells, including increased PD-1 expression. Bulk RNA-seq revealed an M2-like macrophage signature (CD163, Chil3, Retnla, Marco, Rnase2a) in chemoimmunotherapy-treated tumors, and flow cytometry showed reduced cDC1 activation; both were reversed by GDF-15 blockade.\nConclusions: These findings suggest that therapy-induced GDF-15 contributes to resistance to platinum- and taxane-based PD-1 combinations and may exacerbate treatment-related toxicity. Neutralizing GDF-15 restores antitumor CD8+ T cell immunity, reprograms suppressive myeloid states, and improves the overall activity and tolerability of combined PD-1 blockade and cytotoxic chemotherapy. GDF-15 inhibition therefore holds potential to enhance responses to first-line chemoimmunotherapy in tumors such as NSCLC and UC.", "source_company": "CatalYm GmbH", "source_org_type": "公司", "row_number": 1204, "target_meta": "GDF15", "MOA_meta": "抑制剂"}, {"drug_name": "NW024-1", "company": "Chengdu Chipscreen NewWay Biosciences Co., Ltd.", "org_type": "公司", "target": "ALPP/ALPPL2", "modality": "ADC", "importance_level": "高", "total_score": 76.5, "institution_score": 75, "track_score": 85, "milestone_score": 70, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "NW024-1为靶向ALPP/ALPPL2的ADC，肿瘤表达高且正常组织表达低，具有良好选择性；机构为国内知名Chipscreen旗下专注大分子子公司，ADC赛道热门且体外体内显示强效肿瘤消退，支持较高综合评分。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5369", "id": "i57ACZ0BZznHJdntgtVn", "source_drug_name": "NW024-1", "title": "NW024-1, a novel ALPP/ALPPL2-targeting antibody drug conjugate with a topoisomerase 1 inhibitor payload, demonstrates potent antitumor efficacy", "abstract_text": "Background: Placental alkaline phosphatases, ALPP and ALPPL2, are highly homologous (97%) membrane-bound proteins involved in fetal development. They are highly expressed in a variety of tumor cells including ovarian (70%), endometrial (41%), lung (NSCLC, 25%) and gastric (25%), but have limited expression levels in normal tissues, making them ideal targets for the development of antibody-drug conjugates (ADCs). Here, an ALPP/ALPPL2-targeting ADC NW024-1 was developed, consisting of a humanized IgG1 anti-ALPP/ALPPL2 antibody conjugated via a hydrophilic linker to a topoisomerase 1 inhibitor payload (TOP1i), designed to selectively deliver the cytotoxic agent to ALPP/ALPPL2-expressing cells. NW024-1 was tested in vitro and in vivo to evaluate its therapeutic potential.\nMethods: A library of ALPP/ALPPL2-binding clones was screened for cell binding, internalization and affinity. The humanized antibody was conjugated to the TOP1i payload with DAR8 using a cleavable linker. The in vivo efficacy of NW024-1 was evaluated in a mouse xenograft model of gastric cancer (NCI-N87), administered with a single dose of 3 mg/kg and 10 mg/kg to evaluate anti-tumor activity.\nResults: The antibody showed strong binding to human ALPP/ALPPL2 (EC50 = 1.32 nM) low expressing cells, but no binding to human ALPI /ALPL high expressing cells. In vitro, it displayed robust internalization into ALPP/ALPPL2 positive cells and low nanomolar affinity to ALPP (KD = 1.32 nM) and ALPPL2 (KD = 0.85 nM). NW024-1 showed ALPP/ALPPL2-dependent cell killing. In vivo, NW024-1 achieved near-complete tumor regression (TGI > 95%) at 3 and 10 mg/kg for single dose, and was well tolerated in mice as indicated by body weight.\nConclusions: NW024-1 is a novel ADC exhibiting a favorable profile and potent antitumor efficacy. These findings highlight its promising therapeutic potential for ALPP-expressing tumors and support its further advancement into clinical investigation.", "source_company": "Chengdu Chipscreen NewWay Biosciences Co., Ltd.", "source_org_type": "公司", "row_number": 1230, "target_meta": "ALPP", "MOA_meta": "抗体偶联药物"}, {"drug_name": "EM33", "company": "Shanghai EpimAb Biotherapeutics Co., Ltd.", "org_type": "公司", "target": "未披露", "modality": "ProTCE", "importance_level": "高", "total_score": 76.5, "institution_score": 75, "track_score": 85, "milestone_score": 70, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "EM33为新型双掩蔽Prodrug T cell engager（ProTCE），针对高度表达于多种实体瘤但正常组织低表达的TAA，通过肿瘤特异性蛋白酶激活实现1000倍治疗窗，显著改善CRS等安全性。EpimAb作为国内专注双特异性抗体/TCE的头部biotech，平台创新性强，preclinical数据突出肿瘤抑制和低细胞因子释放，赛道为热门TCE优化方向。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4484", "id": "U57M_5wBZznHJdnt_W7P", "source_drug_name": "EM33", "title": "A novel and versatile Prodrug T cell engager platform with a novel candidate demonstrating potent and tumor-restricted activity", "abstract_text": "T-cell engagers (TCEs) have emerged as a powerful modality of immunotherapies. However, their clinical application, particularly in solid tumors, is limited by on-target, off-tumor toxicities and potentially life-threatening systemic immune activation, such as severe cytokine release syndrome (CRS). To address these challenges, conditionally activated prodrug TCEs (ProTCEs) represent a promising next-generation strategy. Recent efforts have focused on masking either the CD3 binding domain or both CD3 and TAA (tumor associated antigen) binding domain of TCEs. The masking peptide is fused to ProTCE molecules usually through a cleavable linker that can be cleaved by tumor-specific proteases. Despite recent progress, there is still a challenge for balancing efficient masking and tumor-specific activation to achieve a wider therapeutic window. Here, we present a modular ProTCE design that includes a masking peptide screening platform, allowing rapid identification of masking peptides that effectively suppress the antibody binding ability. Moreover, we engineered a proprietary peptide linker that can be recognized and cleaved by multiple tumor specific proteases. This novel linker exhibits exceptional stability in serum to prevent systemic activation, while demonstrating enhanced cleavage efficiency by tumor-associated proteases, ensuring tumor-specific drug activation and exposure. In addition, our platform is flexible to generate single masking (mask CD3 binding domain) or dual masking (mask both TAA and CD3 binding domains) ProTCEs. With this platform, we have generated a pipeline of ProTCE molecules targeting various TAAs. Most notably, we have developed a ProTCE, EM33, targeting a TAA that is highly expressed on multiple solid tumors but also expressed on normal tissues at a low level. This molecule was designed to have both TAA and CD3 binding domains masked. EM33 exhibits minimal activity in its prodrug form; however, upon exposure to proteases, its activity is fully restored, demonstrating a 1000-fold therapeutic window. In a high density PBMC assay, our ProTCE does not induce T-cell activation and cytokine release, in contrast to its unmasked variant. In vivo, this molecule demonstrated significant tumor growth inhibition in multiple PBMC engrafted tumor cell xenograft models. EM33 also exhibited comparable anti-tumor activity to the unmasked TCE while inducing significantly less cytokine release, indicative of its potential enhanced benefit/risk ratio in human.Our ProTCE platform enables the rapid development of conditionally activated TCEs with an improved therapeutic window. The preclinical data for our first candidate highlights the potential of our platform to generate new TCE therapies for cancer patients targeting TAAs, that currently have posed significant safety and/or efficacy challenges to the classical T-cell engaging approach.", "source_company": "Shanghai EpimAb Biotherapeutics Co., Ltd.", "source_org_type": "公司", "row_number": 1240, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "SC3613", "company": "Dong-A ST", "org_type": "公司", "target": "EGFR (mutant-selective)", "modality": "degrader", "importance_level": "高", "total_score": 76.5, "institution_score": 65, "track_score": 90, "milestone_score": 75, "field_heat_score": 85, "bonus_score": 4, "brief_reason": "SC3613为新型异双功能突变选择性EGFR degrader，靶向L858R等突变型EGFR并避免野生型脱靶毒性，在TKI耐药NSCLC模型中显示强效抗瘤活性及更好安全性。机构为韩国中型制药公司、热门PROTAC-like降解剂赛道+EGFR耐药突变高未满足需求、preclinical数据扎实包括异种移植瘤完全缓解，故综合重要性较高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8697", "id": "G1XM_5wBX1NQZOEH-LS6", "source_drug_name": "SC3613", "title": "SC3613 (IN-207387), a mutant-selective EGFR degrader, exhibits potent anti-tumor activity and improved safety profile in EGFR TKI-resistant NSCLC", "abstract_text": "Non-small cell lung cancer (NSCLC) accounts for approximately 85% of all lung cancers, with activating mutations in the epidermal growth factor receptor (EGFR) strongly associated with tumor progression and poor clinical outcomes. Among these mutations, the L858R mutation in exon 21 serves as a major oncogenic driver that confers initial sensitivity to EGFR tyrosine kinase inhibitors (TKIs). However, patients with L858R-driven tumors exhibit a poorer prognosis and shorter progression-free survival even with third-generation EGFR TKIs, such as osimertinib, compared with those harboring exon 19 deletions, underscoring a substantial unmet clinical need in this molecular subgroup. In addition, the emergence of secondary resistance mutations, including C797S, further limits the long-term efficacy of current TKIs. To address these challenges, targeted protein degradation has emerged as a promising strategy to eliminate both activating and resistance-associated mutant EGFR. We developed SC3613 (IN-207387), a novel heterobifunctional degrader designed to selectively bind an allosteric pocket of mutant EGFR while sparing the wild-type receptor, thereby minimizing off-target toxicities. SC3613 efficiently induced ubiquitin-proteasome-mediated degradation across L858R-containing EGFR variants, including L858R/C797S, and exhibited potent anti-proliferative activity in patient-derived cells harboring resistant EGFR mutations. A potent antitumor effect was also observed in NCI-H1975 (L858R/T790M) cells. Consistent with effective target engagement, SC3613 treatment resulted in marked suppression of downstream EGFR signaling pathways. Importantly, SC3613 demonstrated a superior safety profile. In BALB/c nude mice, SC3613 produced substantially lower levels of skin keratosis on the face, neck, and abdomen compared with osimertinib, indicating a reduced incidence of cutaneous adverse effects and a broader therapeutic window. Furthermore, orally administrated SC3613 induced potent, dose-dependent anti-tumor activity in multiple EGFR TKI-resistant xenograft model. Treatment led to a high incidence of durable complete tumor regressions without associated body-weight loss, highlighting its favorable tolerability. Collectively, these findings identify SC3613 as a potent, highly mutant-selective, and orally active EGFR degrader with robust anti-tumor efficacy and improved safety. SC3613 represents a promising next-generation therapeutic candidate for NSCLC patients harboring activating and resistance mutations such as L858R, T790M, and C797S.", "source_company": "Dong-A ST", "source_org_type": "公司", "row_number": 1245, "target_meta": "EGFR", "MOA_meta": "降解剂"}, {"drug_name": "ZM-8195", "company": "Simcere Zaiming Pharmaceutical Co., Ltd.", "org_type": "公司", "target": "ALK", "modality": "inhibitor", "importance_level": "高", "total_score": 76, "institution_score": 75, "track_score": 80, "milestone_score": 70, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "ZM-8195为新型选择性ALK抑制剂，针对ALK融合及复合耐药突变（包括G1202R/L1196M），具有优异TRK选择性及脑渗透性。目前处于IND enabling阶段。先声再明作为国内知名创新药企子公司，在肿瘤领域有较强研发实力，ALK耐药突变覆盖赛道热度高，展示出肿瘤完全消退及脑模型疗效，综合潜力显著。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6428", "id": "z1XM_5wBX1NQZOEH-LG6", "source_drug_name": "ZM-8195", "title": "Discovery of a novel ALK inhibitor ZM-8195 that targets ALK compound mutations with superior TRK selectivity", "abstract_text": "ALK fusions are common oncogenic drivers. Approximately 5% of NSCLC patients are ALK-positive, with 30% to 40% developing brain metastases. ALK inhibitors are primarily used to treat ALK-positive patients. However, sequential therapy with second- and third-generation inhibitors is susceptible to resistance mutations, compromising clinical efficacy. Concurrently, inhibition of TRK-family kinases (TRKA, TRKB, and TRKC) elicits broad central nervous system (CNS) adverse effects, further limiting their utility. Therefore, there is an urgent need to develop a new generation of ALK inhibitors to cover a broader population of drug-resistant mutations with brain penetrance and superior TRK selectivity. Here, we identified ZM-8195, a potent and selective ALK inhibitor. In in vitro evaluation, ZM-8195 showed low nano-molar activities against EML-ALK fusion and G1202R/L1196M mutation in biochemical and cell proliferation assay. ZM-8195 exhibited minimal activity against TRK-family kinases, with selectivity indices for TRKB over ALK wild-type or mutant exceeding 100-fold. ZM-8195 also showed potent anti-proliferation activity in different ALK compound mutant cell lines with IC50 from 0.5-24 nM. ZM-8195 effectively inhibited H3122(EML4-ALK V1) and BaF3(EML4-ALK V1(G1202R/L1196M)) tumor growth with complete tumor regression. In a BaF3 G1202R/L1196M orthotopic brain model, ZM-8195 also demonstrated robust anti-tumor efficacy. ZM-8195 was well tolerated in rodents and non-rodents. Based on its favorable activity, selectivity, pharmacokinetic profiles and safety, ZM-8195 is currently in IND enabling stage.", "source_company": "Simcere Zaiming Pharmaceutical Co., Ltd.", "source_org_type": "公司", "row_number": 133, "target_meta": "ALK", "MOA_meta": "抑制剂"}, {"drug_name": "Daiad-2/15", "company": "StradBio, Inc.", "org_type": "公司", "target": "IL-2/IL-15 receptor (conditional activation on targeted T cells)", "modality": "other", "importance_level": "高", "total_score": 76, "institution_score": 75, "track_score": 85, "milestone_score": 65, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "Daiad-2/15为条件激活型高活性IL-2/IL-15激动剂，通过逻辑门仅针对肿瘤微环境表达PD1和LAG3的T细胞激活，避免系统毒性，体现新机制和安全性提升。StradBio为国外新兴biotech（源自蛋白设计顶尖背景），赛道为精准免疫激动剂热门但preclinical阶段，综合潜力较高获加分。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9601", "id": "p53ECZ0B4z9FlvORyiZD", "source_drug_name": "Daiad-2/15", "title": "Daiad-2/15: A conditionally active, targeted, hyperpotent IL-2/IL-15 immune agonist is safe and effective in vivo", "abstract_text": "Although high-dose interleukin-2 (IL-2) has been approved for the treatment of certain cancers since 1992, widespread use has been limited due to systemic toxicity, including cytokine release syndrome and vascular leak syndrome. Versions of IL-2 with reduced potency have been studied, but these variants have reduced efficacy as well as toxicity. In this report, we describe Daiad-2/15, a computationally designed, highly potent IL-2/IL-15 agonist that is delivered specifically to tumor-targeting T cells without systemic immune activation. Using our DaiadTM platform technology, a logic gate was engineered by splitting Neo-2/15 into two separate pieces. The individual split Neo-2/15 domains are unable to bind or activate the IL-2 receptor complex. By fusing each portion of the cytokine mimetic to a targeting domain, two distinct modules are created, which together constitute Daiad-2/15. In vitro, Daiad-2/15 activates only T cells that express the targeted antigen, with a 10,000-fold lower threshold for signaling compared to antigen-negative T cells. By targeting two different antigens, the Daiad-2/15 acts as an effective ‘AND’ gate, only activating T cells that express both antigens. Furthermore, Daiad-2/15 does not trans-activate target-negative cells, even when present in an admixed culture. The Daiad architecture is compatible with both full length and single-domain antibodies and leads to antigen-specific T cell expansion in vitro. We designed Daiad-2/15 to activate exhausted T cells in the tumor microenvironment using nanobodies specific for PD1 and LAG3. We evaluated the tolerability and antitumor activity of Daiad-2/15 in a stringent syngeneic tumor model, CT26. Individual checkpoint-specific Daiad-2/15 modules had no impact on tumor growth or weight loss, while the wild-type IL-2 and the parental Neo2/15 cytokine mimetic were toxic in vivo. Treating mice with both Daiad-2/15 modules, specific for PD1and LAG3, resulted in significantly improved antitumor activity compared to the two nanobodies alone, with no signs of systemic toxicity. Together, our data suggest that Daiad-2/15 could potentiate the systemic delivery of a highly potent immune agonist to specific immune cells in the tumor microenvironment and draining lymph nodes with a wide therapeutic index. Additional preclinical studies are underway, and clinical testing of Daiad-2/15 is planned.", "source_company": "StradBio, Inc.", "source_org_type": "公司", "row_number": 273, "target_meta": "IL-2R,IL-15R", "MOA_meta": "其他"}, {"drug_name": "CD19-targeting CAR-T product", "company": "Cellanome, Inc.", "org_type": "公司", "target": "CD19", "modality": "CAR", "importance_level": "高", "total_score": 75.8, "institution_score": 75, "track_score": 85, "milestone_score": 60, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "该CD19 CAR-T产品展示单细胞水平的功能异质性和微环境协同作用（包括非转导CD4+ T细胞增强CD8+杀伤），揭示产品特异性细胞动态及优化潜力。Cellanome作为美国有较强融资（超2亿刀）的创新biotech工具/平台公司，CAR-T赛道+单细胞功能分析热度高，但摘要为技术平台展示而非药物自身里程碑推进，故综合评分较高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5300", "id": "tFXM_5wBX1NQZOEH-LO6", "source_drug_name": "CD19-targeting CAR-T product", "title": "Cell killing dynamics and heterogeneity in engineered T-cells measured in live CellCage enclosures", "abstract_text": "Predicting CAR-T clinical efficacy remains a central challenge to the cell therapy field. Existing potency assays generally rely on bulk endpoints and may fail to capture cellular heterogeneity and dynamic interactions governing in vivo efficacy. We developed a technology to reveal CAR-T functional heterogeneity at single-cell resolution. Using CellCage Enclosures™, we encapsulated thousands of CAR-T cells at single-cell density with NALM-6, HeLa, and A549 targets across 1:10 and 25:1 E:T ratios in one experiment, enabling parallel cytotoxicity assessment under diverse conditions. Studies with AIC100, a preclinical ICAM1 CAR-T product, revealed striking heterogeneity: individual CAR-T cells exhibited killing at 55% compared to 80% with multiple cells working together. Optimal activity required both CD4+ and CD8+ CAR-T cells within the same microenvironment, suggesting critical cooperative mechanisms, which were product-specific, and impactful to clinical efficacy. A second CD19-targeting CAR-T product against NALM6 targets showed individual cells could kill effectively (50-60%), though cytotoxicity still improved to more than 80% with multiple effectors—but at different E-T ratios. Interestingly, CD8+ CAR-T killing was enhanced ~30% by non-transduced CD4+ T-cells lacking the CAR construct entirely, demonstrating that therapeutic potency can be modulated by cell-extrinsic factors independent of antigen recognition or cytokine secretion. This approach profiles thousands of cellular interactions per experiment, revealing that CAR-T activity emerges from complex cell-intrinsic properties and microenvironment factors unpredictable from bulk measurements. Each product exhibits unique cellular dynamics requiring individual optimization. The CellCage platform enables identification of potent CAR-T subpopulations and quantification of functional heterogeneity, providing a path toward predictive potency assays and rational optimization of cellular therapeutics.", "source_company": "Cellanome, Inc.", "source_org_type": "公司", "row_number": 773, "target_meta": "CD19", "MOA_meta": "其他"}, {"drug_name": "bispecific T-cell engagers", "company": "HUB Organoids B.V.", "org_type": "公司", "target": "未披露", "modality": "BiTEs", "importance_level": "高", "total_score": 75.8, "institution_score": 75, "track_score": 85, "milestone_score": 60, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "该记录聚焦BiTEs类双特异性T细胞衔接器在类器官共培养平台上的功能验证，靶点未明确披露；HUB作为被Merck收购的器官类器官技术领导者平台提供商，赛道为热门免疫治疗工具开发，preclinical平台创新性强但非药物本身里程碑，综合潜力较高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4570", "id": "vJ7M_5wBZznHJdnt_W3O", "source_drug_name": "bispecific T-cell engagers", "title": "Organoid-T cell co-cultures: A robust platform for bispecific antibody immunotherapy development", "abstract_text": "Recent advances in cancer immunotherapy have significantly improved patient survival across multiple indications. As new treatment strategies and druggable targets emerge, the number of patients eligible for immunotherapy continues to grow. However, translating promising preclinical findings into clinical success remains challenging, as conventional 2D cancer models offer limited predictive value.   We developed an innovative alternative based on the ability of adult stem cells to form three-dimensional organotypic structures within an extracellular matrix. Patient-derived organoids, generated from normal and malignant tissues and stored in high-quality biobanks, yield highly reproducible results. HUB Organoids faithfully recapitulate the complexity of parental tissue, including molecular heterogeneity and morphological and functional traits. Over the last decade, bispecific antibodies (bsAbs) have gained significant attention in cancer treatment, leading to several approved therapies. Bispecific T-cell engagers (BiTEs), a subclass of bsAbs, bring T cells into close proximity with cancer cells and promote immunologic memory, enabling the immune system to more effectively recognize and eliminate tumor cells. To de-risk drug development and accelerate clinical translation, we developed an assay in which labeled tumor organoids are co-cultured with labeled PBMCs and exposed to BiTEs to assess immune cell-mediated cytotoxicity. Fluorescent dyes enable real-time evaluation of cytotoxic activity via high-resolution microscopy, complemented by cytokine secretion analysis to confirm immune cell activation. HUB’s organoid co-culture system is robust and reproducible, providing a dynamic window to evaluate the activity of multiple BiTEs. Organoid-based cytotoxicity assays accurately reflect BiTE-mediated T cell killing, demonstrating that our model captures the expected mechanism of action. This platform offers a powerful tool for developing and validating cancer immunotherapies, helping to de-risk novel strategies through patient-derived models.", "source_company": "HUB Organoids B.V.", "source_org_type": "公司", "row_number": 1085, "target_meta": "not available", "MOA_meta": "双特异性抗体"}, {"drug_name": "BCG047", "company": "Biocytogen", "org_type": "公司", "target": "FOLR1", "modality": "ADC", "importance_level": "高", "total_score": 75.8, "institution_score": 75, "track_score": 85, "milestone_score": 60, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "BCG047为靶向FOLR1的重链抗体药物偶联物（HCAb-ADC），FOLR1在卵巢癌等实体瘤中高表达且为热门靶点，ADC赛道热度高。Biocytogen作为国内领先biotech机构实力较强，但摘要禁运导致仅preclinical阶段且里程碑信息有限，故综合评分较高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11546", "id": "xZ7M_5wBZznHJdnt_W3O", "source_drug_name": "BCG047", "title": "BCG047, a novel heavy chain antibody-drug conjugate targeting FOLR1, demonstrates outstanding preclinical antitumor efficacy", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Biocytogen", "source_org_type": "公司", "row_number": 1233, "target_meta": "FOLR1", "MOA_meta": "抗体偶联药物"}, {"drug_name": "AeroCyte", "company": "AeroCytek, Inc.", "org_type": "公司", "target": "未披露", "modality": "other", "importance_level": "高", "total_score": 75.5, "institution_score": 65, "track_score": 85, "milestone_score": 75, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "AeroCyte为仿生磷脂微泡人工抗原呈递细胞平台，用于支持CAR-T细胞长期ex vivo扩增，实现高达1016倍扩增并维持靶向特异性杀伤功能；机构为专注细胞治疗制造创新的美国小型biotech，获NIH SBIR/STTR资助，赛道为CAR-T生产优化热门领域，preclinical数据强度较高且具重复给药改善实体瘤潜力。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9360", "id": "8VXM_5wBX1NQZOEH-LO6", "source_drug_name": "AeroCyte", "title": "Long-term ex vivo expansion of functional CAR-T cells using the biomimetic AeroCyte-based artificial antigen-presenting cell platform", "abstract_text": "Strategies to sustain CAR-T cell persistence in vivo include enriching stem-like products, repeated infusions of engineered cells, and improving the tumor microenvironment. Peripheral T lymphocytes exhibit remarkable self-renewal, with studies showing up to 1041-fold expansion in syngeneic mice over 10 years (Nature, 2023; 614:762), and similar potential ex vivo, though technical barriers persist. Here, we assessed a biomimetic phospholipid microbubble platform (AeroCyte) designed as artificial antigen-presenting cells (aAPCs) to support long-term ex vivo CAR-T cell expansion. AeroCyte-J, coated with appropriate ligands, mimics natural cell-to-cell (juxtacrine) interactions for T cell stimulation and undergoes spontaneous dissolution in media. We hypothesized this system would enhance ex vivo production of stem-like T cells and enable repeated dosing to overcome hostile in vivo conditions.\nCD4+ T cells were isolated from human blood using anti-CD4-conjugated AeroCyte and activated with anti-CD3/CD28-conjugated AeroCyte (AeroCyte-J328) for two weeks, then restimulated biweekly for about 6 months, achieving up to 1016-fold expansion. Notably, expansion was absent without AeroCyte-J328. Next, three CAR-T cell lines targeting GD2, HLA-A2, or CD19, which were generated from a vial of frozen PBMCs from a different donor, were expanded over seven biweekly cycles using AeroCyte-J328. The expanded cells were CD3⁺ and included both CD4⁺ and CD8⁺ subsets. CAR-T cells from each stimulation cycle were evaluated for target-specific cytotoxicity by co-culturing them for three days without IL-2 with GFP-expressing Raji cells (CD19⁺, HLA-A2⁻, GD2⁻) and T98G cells (CD19⁻, HLA-A2⁺, GD2⁺). Using the number of target cells co-cultured with non-transduced PBMCs as the baseline control (set at 100%), all three CAR-T cell types demonstrated target specificity, particularly at lower effector-to-target (E:T) ratios, as determined by flow cytometry or fluorescence microscopy. Reproducibility was confirmed by expanding CAR-T cell lines derived from one of three additional donor PBMC samples across four biweekly cycles, which produced consistent and comparable results.\nLong-term expansion depended on continuous aAPC stimulation and is attributed to intrinsic T cell self-renewal rather than malignant transformation, given that expansion is AeroCyte-J328-dependent and the improbability of simultaneous malignant transformation across independent cultures. Additional preclinical and clinical validation of this simple and robust platform could make CAR-T therapy more accessible and affordable, as well as enable improved treatment of solid tumors, for example through repeated dosing.\nSupported by NIH grants R44CA265468 & R43CA298530", "source_company": "AeroCytek, Inc.", "source_org_type": "公司", "row_number": 65, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "a best-in-class series of p53 Y220C reactivators", "company": "Onco3R Therapeutics", "org_type": "公司", "target": "p53 Y220C", "modality": "inhibitor", "importance_level": "高", "total_score": 75.5, "institution_score": 65, "track_score": 85, "milestone_score": 75, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "靶向p53 Y220C突变的小分子reactivator，展现>200倍于临床化合物PC14586的体外/细胞 potency及更好成药性，处于preclinical lead优化阶段。Onco3R为新兴欧洲biotech（Galapagos部分资产来源），p53 Y220C赛道具临床验证前景但需突破potency瓶颈，故综合潜力较高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8836", "id": "_p7M_5wBZznHJdnt_W3O", "source_drug_name": "a best-in-class series of p53 Y220C reactivators", "title": "Discovery of a Best-in-Class small molecule p53 Y220C reactivator: Breaking through the potency ceiling", "abstract_text": "The tumor suppressor p53 is inactivated in approximately 50% of human cancers. In about 1% of solid tumors, a specific Y220C point mutation induces p53 misfolding, leading to its inactivation. This mutation also creates a unique, druggable pocket on the protein's surface, making it a promising target for cancer therapy. The first-generation small molecule reactivator (PC14586, Rezatapopt), designed to bind to this pocket, to refold p53 and to restore its tumor-suppressive functions, has shown clinical efficacy in patients harboring the Y220C mutations.\nHowever, this first-generation compound is limited by modest potency, necessitating high dosing in patients. This high-dose requirement increases the risk of adverse events and narrows the therapeutic window, as monotherapy and even more so in combination regimens. As a result, this compound fails to deliver the drug pressure needed to reach full reactivation of this critical tumor suppressor. Thus, there is a clear need to discover and develop a highly potent p53 small molecule reactivator to fully unlock the therapeutic potential of this promising target.\nAt Onco3R Therapeutics, our patient centric approach, integrating deep translational science with rational, structure-based and AI-augmented drug design, has led to the identification of best-in-class series of p53 Y220C reactivators. Our lead series exhibits more than 200-fold superior potency compared to the clinical compound PC14586 (Rezatapopt) across diverse preclinical assays, including biochemical p53 refolding, cellular p53 refolding, and cellular p21 induction.\nImportantly, our lead series, characterized by strong potency and long residence times in vitro, significantly sustains target engagement and P53 reactivation in cells. This profile enables robust activation of the pro-apoptotic protein PUMA and induces potent, selective cytotoxicity in p53 Y220C mutant cells and in an isogenic cell model. In line with their superior cellular activity and in combination with optimized key ADME, safety parameters, and favorable in vivo PK profiles across species, our leads reach similar efficacy in vivo as PC145586 at much lower exposure.\nIn conclusion, we have identified unique p53 Y220C small molecule reactivators with clear best-in-class cellular potency and favorable drug-like properties. We are currently further profiling these leads as potential drug candidates to achieve superior efficacy at substantially lower doses, maximizing the safety window to ultimately deliver better outcomes to cancer patients with p53 Y220C mutations.", "source_company": "Onco3R Therapeutics", "source_org_type": "公司", "row_number": 93, "target_meta": "p53 Y220C", "MOA_meta": "抑制剂"}, {"drug_name": "RCZY-843", "company": "Rongchang Pharmaceuticals, Ltd.", "org_type": "公司", "target": "menin-MLL", "modality": "inhibitor", "importance_level": "高", "total_score": 75.5, "institution_score": 65, "track_score": 85, "milestone_score": 80, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "RCZY-843为第二代menin-MLL抑制剂，针对KMT2A重排或NPM1突变急性白血病，设计克服临床MEN1突变耐药，亲和力及抗瘤活性优于已获批/临床阶段一代药物。机构为国内有一定实力的制药企业，赛道为热门menin抑制领域且具best-in-class潜力，preclinical数据强劲包括优异PK/PD、安全性及动物模型疗效。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8669", "id": "Up7M_5wBZznHJdnt_W7P", "source_drug_name": "RCZY-843", "title": "RCZY-843: A potential best-in-class, second-generation menin-MLL inhibitor engineered to overcome clinically observed menin-mutation-mediated resistance, with superior preclinical efficacy and safety in acute leukemia models", "abstract_text": "Menin, encoded by the MEN1 gene, is a ubiquitously expressed scaffold protein that regulates gene transcriptions and key signaling pathways. The menin-MLL1 (KMT2A) complex drives aberrant HOX/MEIS1 expression, promoting leukemogenesis in KMT2A-rearranged or NPM1-mutant acute leukemias. Disrupting this interaction is a validated therapeutic strategy, as evidenced by FDA approvals of Syndax’s revumenib (initially for R/R KMT2A-rearranged acute leukemia in November 2024, expanded to R/R NPM1-mutant AML in October 2025) and Kura’s ziftomenib (for R/R NPM1-mutant AML in November 2025). However, first-generation menin inhibitors rapidly develop clinical acquired resistance driven by MEN1 somatic mutations—especially loss-of-function alterations eliminating menin dependency—urgently requiring next-generation, mutation-resilient menin inhibitors. Herein, we report RCZY-843, a novel, highly potent, orally bioavailable second-generation menin-MLL inhibitor with superior preclinical efficacy against acute leukemias. Surface plasmon resonance assays show its picomolar binding affinity to wild-type menin—4-fold and 5-fold stronger than SNDX-5613 and KO-539, respectively. Fluorescence polarization assays further confirm its potent disruption of the menin-MLL interaction in the presence of clinically observed resistance mutations (M327I/V, G331R, T349M) with substantially lower IC₅₀ values than approved or clinical-stage menin inhibitors (SNDX-5613, KO-539, JNJ-75276617). RCZY-843 exerts potent growth inhibition in KMT2A-rearranged/NPM1-mutant cell lines, with >476-fold selectivity over wild-type MLL HL-60 cells and demonstrates favorable drug-like properties, including robust in vitro ADME characteristics, a clean safety profile (hERG IC₅₀ >30 µM), and excellent pharmacokinetics across preclinical species. Notably, it exhibits a longer half-life (T₁/₂) and ~3-fold higher oral bioavailability than SNDX-5613 in rat. In AML xenograft models (MV-4-11, OCI-AML-3), orally administered RCZY-843 achieves tumor growth inhibition comparable to SNDX-5613 at only one-third to one-tenth of the dose, accompanied by higher plasma exposure and preferential tumor distribution. Compared to SNDX-5613, RCZY-843 further demonstrates favorable PK/PD characteristics—including stronger and more durable MEIS1 mRNA suppression—along with good in vivo tolerability, and a wide therapeutic window, as supported by a 14-day rat DRF toxicity study. In conclusion, RCZY-843 is a potential best-in-class, second-generation menin-MLL inhibitor capable of overcoming MEN1 mutation-mediated acquired resistance, with robust preclinical efficacy and a favorable safety profile for the treatment of KMT2A-rearranged/NPM1-mutant acute leukemias.", "source_company": "Rongchang Pharmaceuticals, Ltd.", "source_org_type": "公司", "row_number": 115, "target_meta": "not available", "MOA_meta": "抑制剂"}, {"drug_name": "AV-L03", "company": "Aarvik Therapeutics", "org_type": "公司", "target": "未披露", "modality": "ADC", "importance_level": "高", "total_score": 75.5, "institution_score": 65, "track_score": 90, "milestone_score": 70, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "AV-L03为新型短亲水β-葡糖苷酸酶可裂解连接子结合exatecan payload的ADC，靶点未披露但展示优于Enhertu的亲水性、稳定性和体内疗效，exatecan较DXd更强效且具有更好渗透和旁观者效应。Aarvik作为专注ADC的国外创新biotech虽处于种子阶段但技术亮点突出、赛道极热、preclinical数据较强故综合评分较高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8771", "id": "Kp7M_5wBZznHJdnt_W3O", "source_drug_name": "AV-L03", "title": "Exatecan payload-based antibody-drug conjugates with a short hydrophilic beta-glucuronidase cleavable linker", "abstract_text": "Antibody-drug conjugates (ADCs) enable the specific targeting of a potent cytotoxic drug to cancer cells expressing a select antigen via the release of the cytotoxin covalently linked to a target-specific antibody. A classic ADC comprises three elements: (a) a target-specific antibody that enables the binding of the ADC to cells expressing the target antigen, (b) a potent cytotoxic drug (payload) that kills cells when released from the ADC, and (c) a linker that covalently links the payload to the antibody until pre-defined conditions cause release of the payload. One of the factors limiting the in vivo biological activity of an ADC is high hydrophobicity, which stems partly from the linker or spacer and partly from the payload. In the body, high hydrophobicity often leads to aggregation of the ADC molecules; these aggregates are then rapidly cleared from circulation by the liver. Several approaches investigated in the past to reduce the overall hydrophobicity of ADCs include (a) reducing the hydrophobicity of the payload itself, (b) positioning the (hydrophobic) payload in a shielded pocket of the antibody, and (c) modifying the linker structure by introduction of hydrophilic spacers such as polyethylene glycol (PEG), polysarcosine (PSAR), hydrophilic macrocycles or long hydrophilic XTEN peptides. However, all these linker modifications involve bulky spacers, which can impact permeability into tumor tissue. Our goal was to develop short, streamlined hydrophilic linkers that boost ADC solubility without adding significant bulk. We successfully synthesized and screened several linker-payloads, and validated a novel hydrophilic, lysosomal β-glucuronidase cleavable linker combined with a short sugar-based spacer (AV-L03). We synthesized an ADC comprising trastuzumab conjugated to an exatecan payload via this novel, short, stable, hydrophilic linker AV-L03 at a drug-to-antibody ratio (DAR) of 8 and compared it to Enhertu®, which comprises trastuzumab conjugated to a DXd payload via a (hydrophobic) tetrapeptide linker. The ADC with the novel AV-L03 linker showed superior hydrophilicity, in vitro cytotoxicity, improved plasma stability, and in vivo efficacy in a mouse xenograft model compared to Enhertu®. The AV-L03 linker makes possible the use of exatecan as a payload for ADCs, which is promising given that exatecan is a more potent inhibitor of TOP1 isomerase compared to DXd, with higher permeability and bystander activity, and is a poorer substrate for some MDR pumps. Moreover, the AV-L03 linker, the shortest hydrophilic linker reported to date, is compatible with diverse payloads, and thus opens up several avenues for the design of superior ADCs.", "source_company": "Aarvik Therapeutics", "source_org_type": "公司", "row_number": 122, "target_meta": "not available", "MOA_meta": "抗体偶联药物"}, {"drug_name": "LYW-105", "company": "LyncBio Therapeutics Co., Ltd.", "org_type": "公司", "target": "未披露", "modality": "bispecific ADC", "importance_level": "高", "total_score": 75.5, "institution_score": 65, "track_score": 90, "milestone_score": 70, "field_heat_score": 85, "bonus_score": 3, "brief_reason": "LYW-105为新型双特异性ADC，采用1+1格式双靶点设计、优化的连接子和拓扑异构酶I抑制剂有效载荷，展现出优于基准单靶点ADC的体外/体内疗效、更广治疗窗和良好耐受性。机构为国内新兴biotech，得分中等；赛道为热门bispecific ADC+同类最佳设计，preclinical数据扎实具亮点。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4338", "id": "TFXM_5wBX1NQZOEH-LK6", "source_drug_name": "LYW-105", "title": "LYW-105: A novel bispecific antibody-drug conjugate with enhanced antitumor efficacy and broader therapeutic index", "abstract_text": "Introduction: Antibody-drug conjugates (ADCs) have made remarkable progress in cancer therapy; however, the development of ADCs with a wide therapeutic window that can effectively combat drug resistance and tumor recurrence remains a significant challenge. The fourth-generation ADC developed by LyncBio features homogeneous conjugation, a target-fit linker-payload design, and superior drug-like properties, aiming to break through the limitations of existing ADC therapeutic indices. LYW-105 is an innovative bispecific ADC designed to achieve more extensive and profound tumor regression through a dual-target approach. Its bispecific antibody components utilize a 1+1 format, with each arm demonstrating high affinity and efficient internalization, thereby enhancing therapeutic efficacy by addressing tumor heterogeneity and minimizing resistance. The linker design of LYW-105 allows for rapid lysosomal release and excellent buffer stability, resulting in reduced systemic toxicity and favorable pharmacokinetics. The payload is a topoisomerase I inhibitor with optimal potency and membrane permeability, effectively balancing tumor cytotoxicity with bystander effects.\nMethods: We assessed the binding affinity of the bispecific antibody to its targets using ELISA, FACS, and BLI techniques. Internalization activity was measured using the pHrodo method, while developability was evaluated through methods such as SEC and HIC. The efficacy of LYW-105 was tested both in vitro and in vivo using established solid tumor models.\nResults: In vitro studies showed that LYW-105 exhibited strong binding affinity to its targets and demonstrated approximately 2- to 30-fold greater internalization activity in tumor cell lines compared to reference monoclonal antibodies. Additionally, LYW-105 displayed 2- to 25-fold enhanced inhibition of tumor cell proliferation compared to in-house benchmark ADCs. Biophysical properties and stability assessments at 40°C indicated good developability, comparable to that of monoclonal antibodies. In vivo, LYW-105 demonstrated robust antitumor activity in mouse models, showing superior efficacy and prolonged tumor suppression compared to benchmark ADCs. Body weight changes remained stable across treatment groups, indicating that LYW-105 is well-tolerated.\nConclusions: In summary, LYW-105 has been thoroughly compared to benchmark single-target ADCs in preclinical settings. It demonstrated potent cytotoxicity in vitro and significant antitumor activity in vivo across various tumor cell lines, showcasing a broader therapeutic index than benchmark ADCs.", "source_company": "LyncBio Therapeutics Co., Ltd.", "source_org_type": "公司", "row_number": 143, "target_meta": "not available", "MOA_meta": "抗体偶联药物"}, {"drug_name": "ProTCE-PSMA", "company": "ShangHai Hengrui Pharmaceuticals Co., Ltd.", "org_type": "公司", "target": "PSMA/CD3", "modality": "prodrug", "importance_level": "高", "total_score": 75.5, "institution_score": 85, "track_score": 90, "milestone_score": 40, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "ProTCE-PSMA为新型PSMA/CD3 prodrug形式的T细胞接合剂（TCE），针对前列腺癌，属于热门的双特异性TCE赛道且具prodrug设计潜在安全性优势。恒瑞作为国内头部pharma机构实力强，但因摘要禁运仅preclinical阶段无具体数据，里程碑分较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11544", "id": "6VXM_5wBX1NQZOEH-LC5", "source_drug_name": "ProTCE-PSMA", "title": "ProTCE-PSMA, a novel therapeutic PSMA/CD3 prodrug for prostate cancer", "abstract_text": "Abstract is embargoed at this time.", "source_company": "ShangHai Hengrui Pharmaceuticals Co., Ltd.", "source_org_type": "公司", "row_number": 150, "target_meta": "CD3,PSMA", "MOA_meta": "其他"}, {"drug_name": "SCR-A019", "company": "Simcere Pharmaceutical Group", "org_type": "公司", "target": "MSLN", "modality": "ADC", "importance_level": "高", "total_score": 75.5, "institution_score": 75, "track_score": 85, "milestone_score": 60, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "SCR-A019为靶向MSLN的双表位ADC，采用新型拓扑异构酶I抑制剂payload，旨在克服MSLN脱落问题。Simcere作为国内TOP创新药企，ADC赛道及双表位设计热门，但仅preclinical阶段，整体潜力较高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4453", "id": "N57M_5wBZznHJdnt_W7O", "source_drug_name": "SCR-A019", "title": "SCR-A019, a first-in-class biparatopic ADC targeting MSLN, with a novel topoisomerase I inhibitor demonstrates encouraging efficacy in preclinical models", "abstract_text": "Background: Mesothelin (MSLN) is a GPI-anchored glycoprotein that is expressed on many cancers but limited in normal tissues, which makes it an attractive target for antibody-based cancer therapy. However, MSLN is shed from surface of cells at high levels via proteases that cleave at its membrane-proximal C-terminal region. Shed MSLN accumulates in patient fluids and tumors and can block anti-MSLN antibodies from killing cancer cells. To overcome the challenge of MSLN shedding, we developed a novel biparatopic ADC which prefers binding to membrane MSLN rather than soluble MSLN.\nMethod & Results: The biparatopic ADC SCR-A019 is conjugated with novel topoisomerase 1 inhibitor (CPT116) via a hydrophilic cleavable linker at DAR 6. SCR-A019 specifically recognizes human MSLN with high affinity and showed enhanced internalization and binding capacity compared to parental monoclonal antibody ADC and benchmark ADC in multiple tumor cell lines. In vitro cytotoxicity experiment demonstrated that SCR-A019 induced tumor cell lysis. Compared to benchmark ADC, SCR-A019 drived potent cytotoxicity in the presence of soluble MSLN. In vivo, SCR-A019 showed specific, dose-dependent anti-tumor efficacy toward MSLN positive tumor xenografts including lung and ovary cancer cells. Besides, SCR-A019 exhibited stronger anti-tumor activity than their parental monoclonal-ADC or benchmark ADC. SCR-A019 also have very good stability and favorable developability.\nConclusion: These preclinical data demonstrated SCR-A019 could be a potential first-in-class biparatopic BsADC to overcome the obstacles in antibody-based MSLN-targeting cancer therapy.", "source_company": "Simcere Pharmaceutical Group", "source_org_type": "公司", "row_number": 170, "target_meta": "MSLN", "MOA_meta": "抗体偶联药物"}, {"drug_name": "AVA-ADR", "company": "Avammune Therapeutics", "org_type": "公司", "target": "ADAR1 p150 Zα domain", "modality": "inhibitor", "importance_level": "高", "total_score": 75.5, "institution_score": 65, "track_score": 85, "milestone_score": 75, "field_heat_score": 80, "bonus_score": 8, "brief_reason": "靶向ADAR1 p150 Zα domain的first-in-class小分子抑制剂，通过诱导IFN响应和Z-RNA积累增强抗肿瘤免疫并协同PD-1抑制。Avammune作为国外创新biotech有较强潜力，赛道新颖机制+preclinical强效数据+ADC payload潜力获高分。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5181", "id": "RFXM_5wBX1NQZOEH-LK6", "source_drug_name": "AVA-ADR", "title": "First-in-class Zα-domain-targeted ADAR1 p150 inhibitor demonstrates potent antitumor efficacy in high IFN syngeneic melanoma", "abstract_text": "Background: ADAR1 (Adenosine deaminase acting on RNA) exists in two isoforms: the nuclear p110 and the p150, which shuttles between the nucleus and cytoplasm. ADAR1 p150 promotes immunotherapy resistance by suppressing immunogenic dsRNAs, and by preventing the accumulation of Z-RNA structures. Loss of ADAR1 leads to Z-RNA buildup, activating ZBP1 and triggering necroptosis. Tumors exhibiting high IFN signatures enhance synthetic lethality when ADAR1 is inhibited, while also upregulating PD-L1. This dual effect presents an opportunity for synergistic efficacy for ADAR1 inhibition and checkpoint inhibitors. In this context, we report the discovery of a novel, first-in-class inhibitor that specifically targets the Zα domain of ADAR1 p150 for cancer immunotherapy. Additionally, we evaluated the potential of this ADAR1 p150 inhibitor as a novel payload delivered via PD-L1-targeted ADCs.\nMethods: A series of ADAR1 p150 inhibitors (AVA-ADR) were identified using a high-throughput binding assay, Zα domain binding confirmed by FRET assay. The anti-tumor efficacy of AVA-ADR compounds was assessed in a B16F10 syngeneic melanoma mouse model, both as a monotherapy and in combination with anti-PD-1 therapy in a high interferon condition. AVA-ADR compounds were also evaluated as a novel payload for PDL1 targeted ADCs.\nResults: We identified a novel series of small-molecule inhibitors of ADAR1 p150 that elicits a robust interferon response. Binding studies showed AVA-ADR compounds exhibit submicromolar Zα-domain affinity, surpassing prior inhibitors. AVA-ADR inhibitors displayed nanomolar EC50 values and significant anti-tumor activity in the B16F10 melanoma model. AVA-ADR compounds demonstrate additive efficacy in combination with anti-PD1 treatment (~1.5 X vs anti-PD1). AVA-ADR compounds demonstrate strong anti-tumor potency in high interferon environment, >1.5x superior mIFN- β alone. Tumor samples from the combination group showed significantly elevated expression of interferon-stimulated genes and T-cell activation markers.\nConclusion: To our knowledge no selective small molecule inhibitors of ADAR1 p150 targeting the Za domain have been reported so far. Our SAR approach yielded several next generation Zα binders with nM potency demonstrating effective and competitive displacement of the tightly bound Z-DNA. Next generation compounds demonstrate low nM interferon dependent toxicity in OE21 cell lines. In vivo efficacy study in B16F10 melanoma model demonstrates synergistic efficacy of AVA-ADR compounds with mIFN-β. This is the first disclosure of a selective ADAR1 p150 inhibitor that was systemically administered demonstrating strong anti-tumor potency in high IFN tumors. Furthermore, these inhibitors show promise as payloads for antibody-drug conjugates (ADCs), enabling targeted delivery and enhanced therapeutic index in IFN-responsive cancers.", "source_company": "Avammune Therapeutics", "source_org_type": "公司", "row_number": 214, "target_meta": "ADAR", "MOA_meta": "抑制剂"}, {"drug_name": "BCG029", "company": "Biocytogen", "org_type": "公司", "target": "ADAM9", "modality": "ADC", "importance_level": "高", "total_score": 75.5, "institution_score": 70, "track_score": 85, "milestone_score": 70, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "BCG029为靶向ADAM9的ADC，采用新型拓扑异构酶I抑制剂有效载荷，在PDX模型中显示出强劲疗效。机构为国内知名biotech，ADC+新兴靶点赛道热度高，preclinical数据扎实但摘要仍保密导致阶段信息有限。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11554", "id": "ulXM_5wBX1NQZOEH-LK6", "source_drug_name": "BCG029", "title": "BCG029: An ADAM9-targeting ADC featuring a novel topoisomerase I inhibitor payload demonstrated potent efficacy in PDX models", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Biocytogen", "source_org_type": "公司", "row_number": 219, "target_meta": "ADAM9", "MOA_meta": "抗体偶联药物"}, {"drug_name": "TY-3659", "company": "TYK Medicines, Inc.", "org_type": "公司", "target": "PI3Kα (pan-mutant selective)", "modality": "inhibitor", "importance_level": "高", "total_score": 75.5, "institution_score": 75, "track_score": 85, "milestone_score": 60, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "TY-3659为TYK Medicines开发的allosteric pan-mutant selective PI3Kα抑制剂，并具有降解突变型PI3Kα蛋白的独特机制，靶向PIK3CA热点突变癌症。机构为国内临床阶段biotech（有多个临床管线并上市），赛道为热门突变选择性PI3Kα+蛋白降解机制，preclinical数据强于竞品但仍早期，故综合评分较高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6431", "id": "zVXM_5wBX1NQZOEH-LO6", "source_drug_name": "TY-3659", "title": "Identification and characterization of pan-mutant selective PI3Kα inhibitors with the capability of PI3Kα H1047R protein degradation", "abstract_text": "Introduction: PIK3CA, a PI3K isoform, is one of the most frequently mutated genes in human cancers. PIK3CA mutations are highly enriched at “hotspot” sites in the helical (E542K, E545K) and kinase (H1047R/L) domains. Orthosteric inhibitors of PI3Kα, such as alpelisib and inavolisib, have been approved for the treatment of patients with advanced HR+/HER2− breast cancer. Selective targeting of mutant PI3Kα is anticipated to enhance antitumor efficacy and mitigate the toxicity associated with wild-type PI3Kα inhibition in normal tissue. Allosteric and mutant-selective PI3Kα inhibitors, including RLY-2608 (NCT06982521) and LY4064809 (STX-478, NCT07174336), have been successfully developed in the clinical phase III stage.\nResults: Several allosteric and potent pan-mutant PI3Kα inhibitors developed by TYK Medicines exhibited high selectivity over wild-type (WT) PI3Kα. Our observations revealed that the compounds inhibited AKT phosphorylation in the T47D (PI3Kα H1047R) cell line with an IC50 in the single-digit nanomolar range, demonstrating nearly 200 times more selectivity compared to SK-BR-3 (PI3Kα WT) cells at same time. In in vitro antiproliferative assays, the compounds displayed superior antiproliferative activity against various PI3Kα mutant cells, including T47D, HCC1954 (PI3Kα H1047R), and MCF7 (PI3Kα E545K), compared to STX-478 and RLY-2608. For instance, TY-3659 was four and thirteen times more selective in T47D and MCF7 cells, respectively, than RLY-2608, aligning with the PI3Kα kinase inhibition assays. In addition, TY-3659 effectively degraded PI3Kα mutant protein in HCC1954 and MDA MB 453 (PI3Kα H1047R) cells. In the mouse HCC1954 and Cal33 (PI3Kα H1047R) CDX models, the compounds exhibited potent tumor-inhibitory activity, excellent tolerance, good DMPK properties, and desirable drug-like characteristics. No effects on fasting plasma glucose levels were observed after four days of treatment in the insulin tolerance test.\nIn conclusion, we identified potent allosteric and pan-mutant selective PI3Kα inhibitors capable of degrading PI3Kα mutant protein. Our findings suggest that TYK compounds can significantly enhance the therapeutic index of PI3Kα-mutant cancers without causing PI3Kα WT-related toxicity.\n# Chengshan Niu and Shengli Dong contributed equally to this work.\n*Correspondence authors", "source_company": "TYK Medicines, Inc.", "source_org_type": "公司", "row_number": 247, "target_meta": "PI3Kα", "MOA_meta": "抑制剂"}, {"drug_name": "ABS-106", "company": "Amberstone Biosciences, Inc.", "org_type": "公司", "target": "STEAP1×CD3", "modality": "TCE", "importance_level": "高", "total_score": 75.5, "institution_score": 65, "track_score": 85, "milestone_score": 75, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "ABS-106为基于T-MATE平台的条件激活型STEAP1×CD3 TCE，通过pH门控实现肿瘤选择性激活，解决固瘤TCE毒性难题。Amberstone为创新biotech，赛道热门（条件激活TCE+实体瘤热门靶点），IND-enabling阶段数据强，综合热度高加新机制亮点。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9656", "id": "gZ7M_5wBZznHJdnt_W3O", "source_drug_name": "ABS-106", "title": "Enhancing safety to unlock efficacy: A novel class of conditionally-activated T cell engagers for solid tumors", "abstract_text": "Background: T cell engagers (TCEs) offer potent anti-tumor activity but remain limited in solid tumors by cytokine release and on-target off-tumor toxicity. Amberstone’s Tumor-Microenvironment Activated Therapeutics (T-MATE™) platform enables pH-gated activation of TCEs, exploiting tumor acidity to achieve selective activation within tumors while maintaining potency under heterogenous tumor pHs (up to pH 7.2). We previously demonstrated that T-MATE™ TCEs broaden the therapeutic index and enable selective targeting of tumor antigens such as TROP-2, which were previously intractable due to normal tissue expression.\nMethods: The T-MATE technology integrates proprietary pH-dependent anti-CD3 clones identified via de novo high-throughput functional screening. These clones undergo pH-dependent conformational changes in their CDRs, conferring tunable affinities and selectivity profiles for plug-and-play integration into next-generation TCEs. ABS-106, a STEAP1×CD3 T-MATE TCE, was evaluated for activity against metastatic castration-resistant prostate cancer (mCRPC) using in vitro assays such as cytotoxicity, cytokine release, and repeated-challenge, as well as in vivo xenograft models in humanized mice and non-human primates toxicokinetic studies.\nResults: ABS-106 demonstrated potent cytotoxicity across tumor-relevant pH ≤7.2 and induced sustained T cell activation and cytokine release comparable to a clinical benchmark TCE. Its pH 7.2 gating minimized activity at physiological pH 7.3-7.5, yielding minimal T cell activation and about 1000-fold lower cytokine release even at high STEAP1 expression. ABS-106 effectively killed STEAP1Med-Low tumor cells and mediated bystander killing of STEAP1⁻ cells, sustaining activity over nine tumor rechallenge cycles. In vivo, ABS-106 induced dose-dependent tumor regression with increased intratumoral CD8⁺ T cells infiltration and upregulation of pharmacodynamic markers such as Granzyme B, CD69 and PD-1. ABS-106 is fully cross-reactive to cynomolgus CD3 and STEAP1, and exhibited consistent favorable pharmacokinetics (t₁/₂ 4-5 days) across all animals. Notably, it maintained exposure upon repeat dosing, and was well tolerated at >130× exposure of the benchmark’s reported MTD. The molecule demonstrates excellent developability, robust stability under diverse stress conditions, and strong manufacturability characteristics. ABS-106 is currently undergoing IND-enabling studies.\nConclusions: ABS-106 exemplifies the precision-engineered, next-gen T-MATE™ TCE with optimal safety-efficacy balance. This smarter, safer TCE design enables potent anti-tumor efficacy while minimizing systemic toxicity, representing a promising therapeutic strategy for solid tumors and other indications.", "source_company": "Amberstone Biosciences, Inc.", "source_org_type": "公司", "row_number": 268, "target_meta": "STEAP1,CD3", "MOA_meta": "其他"}, {"drug_name": "anti-CD3 single-domain antibodies (VHHs)", "company": "WuXi Biologics", "org_type": "公司", "target": "CD3", "modality": "TCE", "importance_level": "高", "total_score": 75.5, "institution_score": 75, "track_score": 90, "milestone_score": 55, "field_heat_score": 85, "bonus_score": 3, "brief_reason": "基于新型抗CD3 VHH构建TCE双抗，靶点CD3在T细胞衔接器领域核心，WuXi Biologics平台技术支持灵活设计与优异成药性。赛道热门且体外体内活性优于部分已上市TCE，综合潜力较高但仍处早期研发阶段。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4491", "id": "7VXM_5wBX1NQZOEH-LC5", "source_drug_name": "anti-CD3 single-domain antibodies (VHHs)", "title": "Novel anti-CD3 single domain antibodies for the development of T cell engager", "abstract_text": "In cancer immunotherapy, CD3 T-cell engager (TCE) bispecific antibodies (BsAbs) represent a pivotal direction in drug development due to their ability to directly recruit T cells for precise elimination of tumor cells. Currently, all approved TCE BsAbs are based on conventional anti-CD3 antibodies consisting of both heavy and light chains. However, these TCEs face challenges in bispecific format design and complicate manufacturing, due to their structural complexity. In contrast, TCEs based on anti-CD3 single-domain antibodies (sdAbs, or VHHs) enable modular assembly into compact bispecific molecules. This approach avoids the light chain mispairing issue and allows for more flexible molecular design. Their simpler architecture streamlines production, especially for multi-specific constructs. Moreover, smaller VHHs may facilitate formation of more effective immune synapses. WuXi Biologics has developed a panel of anti-CD3 VHHs with novel sequences derived from immunized llama phage display libraries. These VHHs exhibit a range of binding affinities to CD3 and varying potencies in T-cell activation. TCE molecules constructed using these CD3 VHHs demonstrate potent T cell-dependent tumor cell killing efficacy both in vitro and in vivo. Compared with some marketed TCEs, our VHH-based CD3 TCE molecules show superior in vivo efficacy with comparable cytokine profiles. Additionally, these humanized VHHs display excellent developability characteristics.", "source_company": "WuXi Biologics", "source_org_type": "公司", "row_number": 295, "target_meta": "CD3", "MOA_meta": "其他"}, {"drug_name": "TCE-A", "company": "ShangHai Hengrui Pharmaceuticals Co., Ltd.", "org_type": "公司", "target": "CD19×CD20×CD3", "modality": "TCE", "importance_level": "高", "total_score": 75.5, "institution_score": 85, "track_score": 90, "milestone_score": 40, "field_heat_score": 85, "bonus_score": 2, "brief_reason": "TCE-A为恒瑞医药开发的OR-gate CD19×CD20×CD3三特异性T细胞衔接器，靶向B细胞恶性肿瘤和自身免疫病热门靶点，trispecific TCE赛道热度高。公司为国内头部pharma机构实力强，但摘要被禁运仅体现preclinical阶段，无具体数据里程碑。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11553", "id": "_VXM_5wBX1NQZOEH-LC5", "source_drug_name": "TCE-A", "title": "TCE-A: An “OR-gate” CD19×CD20×CD3 trispecific T-cell engager for B-cell malignancies and autoimmune diseases", "abstract_text": "Abstract is embargoed at this time.", "source_company": "ShangHai Hengrui Pharmaceuticals Co., Ltd.", "source_org_type": "公司", "row_number": 307, "target_meta": "CD19,CD20,CD3", "MOA_meta": "其他"}, {"drug_name": "CD3/CD20 bispecific antibody", "company": "GemPharmatech Co., Ltd.", "org_type": "公司", "target": "CD3/CD20", "modality": "bispecific antibody", "importance_level": "高", "total_score": 75.5, "institution_score": 65, "track_score": 90, "milestone_score": 70, "field_heat_score": 80, "bonus_score": 0, "brief_reason": "该CD3/CD20双抗为T细胞衔接器（TCE）类热门免疫治疗药物，靶向CD20用于淋巴瘤模型评估，赛道热度高；GemPharmatech作为国内领先CRO和基因工程小鼠模型提供商（上市公司，全球最大模型库之一），在体外+多种人源化/免疫缺陷模型中展示清晰的肿瘤生长抑制（81.5%），preclinical平台强度较强。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/7158", "id": "GVXM_5wBX1NQZOEH-LG5", "source_drug_name": "CD3/CD20 bispecific antibody", "title": "An integrated preclinical platform for comprehensive evaluation of T-Cell engagers", "abstract_text": "T-cell engagers (TCEs) are bispecific antibodies designed to bind both CD3 on T cells and a tumor-associated antigen (TAA) on cancer cells, representing a promising class of immunotherapies. Given their complex mechanisms of action, physiologically relevant preclinical models are essential for accurately evaluating the efficacy and safety profiles of TCE candidates. We developed a panel of medium- to high-throughput in vitro assays to screen TCEs based on target binding, T-cell activation, and tumor cell killing capabilities. Lead candidates were further assessed using in vivo efficacy studies in both xenograft and syngeneic models. In xenograft studies, we utilized NCG mice and NCG-MHC-dKO mice—the latter generated by deleting murine MHC class I and II genes in the NCG background—to reduce graft-versus-host disease (GvHD) after human PBMC engraftment and extend the experimental observation period. AMG509 (targeting STEAP1), AMG757 (targeting DLL3), and IBI-389 (targeting CLDN18.2) were evaluated in models of prostate cancer, small-cell lung cancer, and patient-derived xenografts (PDX), respectively. For syngeneic studies, we used BALB/c-hCD3EDG mice, in which endogenous Cd3e, Cd3d, and Cd3g genes were replaced with human versions. These mice were engrafted with A20-hCD20 lymphoma cells to test a CD3/CD20 bispecific antibody.\nBoth AMG509 and AMG757 significantly suppressed tumor growth in PBMC-humanized NCG and NCG-MHC-dKO models, with no major adverse effects on animal health. The efficacy of AMG509 varied across prostate cancer cell lines with different levels of STEAP1 expression. In NCI-H69 tumor-bearing mice treated with AMG757, the degree of tumor response correlated with the extent of human immune cell reconstitution observed three weeks post-treatment. IBI-389 exhibited marked tumor growth inhibition in two gastric cancer PDX models and one pancreatic cancer PDX model. In the BALB/c-hCD3EDG syngeneic model, administration of the CD3/CD20 bispecific antibody led to 81.5% tumor growth inhibition after 18 days.\nGemPharmatech’s integrated strategy—combining in vitro screening with a range of in vivo models such as NCG, NCG-MHC-dKO, and CD3-humanized mice—enables rapid, scalable, and translationally relevant assessment of T-cell engager candidates. This comprehensive platform supports robust and efficient immuno-oncology drug discovery and development.", "source_company": "GemPharmatech Co., Ltd.", "source_org_type": "公司", "row_number": 326, "target_meta": "CD3,CD20", "MOA_meta": "双特异性抗体"}, {"drug_name": "Oncuria-Detect", "company": "Nonagen Bioscience", "org_type": "biotech company", "target": "未披露", "modality": "multiplex immunoassay", "importance_level": "高", "total_score": 75.5, "institution_score": 75, "track_score": 70, "milestone_score": 80, "field_heat_score": 75, "bonus_score": 0, "brief_reason": "Oncuria-Detect为尿液多重免疫分析法检测膀胱癌相关10种蛋白签名，实现高敏感性无创诊断。机构为专注癌症诊断的biotech公司，赛道为液体活检诊断工具开发阶段较成熟且前瞻性大型试验显示优于传统方法。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10202", "id": "w1XM_5wBX1NQZOEH-LG6", "source_drug_name": "Oncuria-Detect", "title": "Detection of bladder cancer in patients with gross hematuria using Oncuria-Detect, a urine-based multiplex immunoassay", "abstract_text": "Background - Cystoscopy is standard of care in evaluating patients with gross hematuria for bladder cancer with hematuria being the primary sign of bladder cancer. Oncuria-Detect, a liquid biopsy to detect de novo bladder cancer from a single voided urine sample demonstrated favorable performance.\nMethods - To investigate whether Oncuria-Detect, a multiplex immunoassay that detects a urothelial cancer associated diagnostic signature composed of 10 proteins in voided urine could improve detection of urothelial cancer while evaluating participants with gross hematuria. From September 2016 through July 2025, 9 academic, private practice, and hospital facilities in the US and Japan prospectively enrolled 450 participants with gross hematuria into this urothelial cancer evaluation study. Diagnosis of urothelial cancer was based on cystoscopy (or ureteroscopy) with biopsy, which is accepted as the reference standard. Prior to the cystoscopic/ureteroscopic evaluation, participants provided a urine sample for analysis of Oncuria-Detect and BladderChek (analyzed in a blinded manner) as well as urine cytology. The performance of Oncuria-Detect was compared with BladderChek and urine cytology as an aid to detect de novo urothelial cancer with cystoscopy/ureteroscopy and histological evaluation.\nResults - Urothelial cancer was diagnosed in 97 participants (4 of whom had upper tract urothelial carcinoma and 93 with urothelial carcinoma of the bladder). The Oncuria-Detect assay was positive in 80 of 97 participants with cancer resulting in a sensitivity of 82.6% (95% CI, 74.9%-89.6%) with a specificity of 33.3% (95% CI, 28.7%-38.7%) and 88.4% adjusted negative predictive value (NPV) (95% CI, 83.8%-93.0%). BladderChek results were positive in 16 of 97 participants resulting in a sensitivity, 16.4% (95% CI, 10.0%-23.5%) with a specificity of 99.2% (95% CI, 98.0%-100.0%) and 82.6% adjusted NPV (95% CI, 81.5%-83.7%), whereas cytology test results were positive in 35 of 97 participants with a noted sensitivity of 35.7% (95% CI, 26.5%-46.1%) at a specificity of 99.7% (95% CI, 99.1%-100.0%) and 86.1% adjusted NPV (95% CI 84.4-88.1). Oncuria-Detect sensitivity remained high for low-grade 81.7% (95% CI, 67.2%-94.7%) vs. high grade 82.7% (95% CI, 74.2%-90.9%) and NMIBC 82.9% (95% CI, 74.4%-90.8%) vs. MIBC 79.8% (95% CI, 61.3%-94.7%).\nConclusions - In this large prospective trial, Oncuria-Detect, had a substantially superior sensitivity compared to both BladderChek and urinary cytology in detecting de novo urothelial cancers, allowing it to effectively rule out approximately 30% of individuals presenting for gross hematuria evaluation.", "source_company": "Cedars-Sinai Medical Center", "source_org_type": "医院", "row_number": 448, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "Stealth-Body (SB) Fc ADC", "company": "CrossPoint Therapeutics", "org_type": "公司", "target": "未披露", "modality": "ADC", "importance_level": "高", "total_score": 75.5, "institution_score": 65, "track_score": 90, "milestone_score": 70, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "Stealth-Body平台通过Fc沉默突变显著降低ADC的FcγR介导脱靶毒性，同时保持抗肿瘤疗效，属于热门ADC赛道优化技术。公司为2022年成立的韩国新兴biotech，已获Pre-A融资并展示优于LALA的PK和毒性数据。打分基于国内TOP biotech潜力、ADC+Fc工程高热度、扎实preclinical（CDX模型MED 0.6mg/kg、NHP毒性进行中）和平台亮点。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5471", "id": "8FXM_5wBX1NQZOEH-LG6", "source_drug_name": "Stealth-Body (SB) Fc ADC", "title": "Maximizing therapeutic index using fully Fc-silent antibody platform", "abstract_text": "Antibody drug conjugates (ADCs) have transformed the clinical landscape for the treatment of cancers over the last two decades spear-headed by intensive research of linker and payload chemistries. However, toxicities remain a concern where impairing dosage and administration frequency of the ADCs could impact overall clinical benefit. We developed Stealth-Body (SB) by introducing specific mutations in the Fc region of the antibody to limit Fc-Fcγ receptor interactions without compromising efficacy and maintaining manufacturing scalability, when compared to LALA mutations, the SB Fc showed improved pharmacokinetic (PK) parameters such as half-life in serum studies in double transgenic mice (huFcRn and hualbumin) and complete loss of binding to all Fcγ receptors as well as C1q. Based on these characteristics, we are developing a ADCs containing SB Fc for selective anti-tumor efficacy and limiting interaction with Fcγ receptors to reduce off-target toxicities. Antibodies containing WT Fc and SB Fcs were conjugated with MMAE and efficacy was determined in in vitro and in vivo studies. Currently, PK studies in mice and preliminary toxicology studies in non-human primates are ongoing. To determine whether SB Fc conjugates were able to avoid off-target toxicities, cancer cell lines expressing FcγRs were treated with SB Fc containing conjugates or WT Fc conjugates. As expected, the SB Fc conjugates displayed no off-target cell killing toxicities in these cell lines compared to WT Fc conjugates. Conjugates containing the SB Fcs maintained potent efficacy in vitro in cancer cell lines similar WT Fc containing conjugates, indicating that efficacy was not compromised by the mutations in the SB Fc. In in vivo cell line derived xenograft (CDX) models, the SB Fc conjugates showed strong tumor growth inhibition (TGI) as single injection doses and similar potent minimum efficacious dose (MED) was observed in CDX models and determined to be 0.6 mg/kg. These preclinical data demonstrate the potential of SB Fc containing ADCs as promising for the treatment of various cancer indications and supports their use for clinical development.", "source_company": "CrossPoint Therapeutics", "source_org_type": "公司", "row_number": 477, "target_meta": "not available", "MOA_meta": "抗体偶联药物"}, {"drug_name": "HER3 (bs)Ab", "company": "Debiopharm International S.A.", "org_type": "公司", "target": "HER3", "modality": "bispecific antibody", "importance_level": "高", "total_score": 75.5, "institution_score": 75, "track_score": 85, "milestone_score": 60, "field_heat_score": 80, "bonus_score": 0, "brief_reason": "药物针对HER3的双特异性抗体，用于优化bsAb和bsADC的靶点表达评估和模型选择，Debiopharm作为专注肿瘤的资深欧洲biotech公司在ADC领域有较强布局。机构实力较强、双抗+ADC赛道热门但该条仅为工具性研究而非具体候选物进展，导致里程碑分中等，总分偏高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4738", "id": "tVXM_5wBX1NQZOEH-LK6", "source_drug_name": "HER3 (bs)Ab", "title": "Beyond bulk: Resolving RNASeq/mass spectrometry/IHC discrepancies with multiplexed spatial profiling and 3D cluster analysis to refine HER3 (bs)Ab and (bs)ADC therapeutic strategies", "abstract_text": "Assessment of target expression for mono- and bispecific antibodies (Ab/bsAb) and antibody-drug conjugates (ADCs/bsADCs) can be challenging due to poor correlation between bulk RNASeq, proteomics and immunohistochemistry (IHC) data. While IHC is sufficient to address single target expression levels at single cell level, multiplexing is required to assess spatial distribution and expression thresholds of multiple targets for bsAb and bsADC use.\nTo address these challenges, we performed a full characterization of (bs)ADC targets in patient-derived xenografts (PDX) across different omics platforms. Based on these outputs, we created a 3D biologics-tailored analysis tool which allows multifactorial target assessment to guide PDX model selection for evaluation of (bs)Ab/ADC sensitivity.\nHER3 and other selected tumor-associated antigens (TAA) were investigated, showing different levels of mRNA/protein correlations and different levels of mass spec-derived proteomics versus IHC. Based on these results, PDX models with a pre-defined TAA expression spectrum were selected for multiplexed spatial proteomics to determine single cell expression intensities and co-localization of those TAAs. Our 3D biologics analysis tool facilitates a multifactorial, granular assessment of the selected targets.\nThe target-specific variability of correlation between the different analytes highlights once again the importance of proper omics/IHC platform selection depending on each individual target. Once the appropriate expression values are identified, the 3D analysis tool allows dynamic adjustment of expression thresholds of multiple targets with the potential to inform on the sample-specific most promising (bs)Ab/ADC treatment options.", "source_company": "Debiopharm International S.A.", "source_org_type": "公司", "row_number": 604, "target_meta": "HER3", "MOA_meta": "双特异性抗体"}, {"drug_name": "GPRC5D multispecific antibodies", "company": "Integral Molecular", "org_type": "公司", "target": "GPRC5D", "modality": "bispecific antibody", "importance_level": "高", "total_score": 75.5, "institution_score": 65, "track_score": 90, "milestone_score": 70, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "靶点为GPRC5D的多特异性抗体（双抗/三抗），采用T细胞衔接机制治疗多发性骨髓瘤，Integral Molecular作为专注膜蛋白抗体发现的美国biotech公司实力较强；赛道热门（GPRC5D在MM领域备受关注，双抗/TCE高热度），虽处preclinical优化阶段但展示强体外/体内活性及亲和力显著提升，综合潜力较高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4523", "id": "CFXM_5wBX1NQZOEH-LO6", "source_drug_name": "GPRC5D multispecific antibodies", "title": "GPRC5D multispecific antibodies: Engineering for affinity, cross-species reactivity, and bi/trispecific engagement in multiple myeloma", "abstract_text": "Background: GPRC5D is a G protein-coupled receptor expressed on multiple myeloma cells but largely absent from healthy tissues, making it an attractive target for T cell-engaging multispecific antibodies. Antibodies that simultaneously engage GPRC5D and other molecules (e.g. BCMA and CD3) to activate T cells are anticipated to provide excellent efficacy as monotherapies. Multipass membrane proteins are valuable therapeutic targets but often inaccessible for antibody discovery due to structural complexity and high conservation. Using our membrane protein-optimized discovery platform (MPS), we generated a panel of GPRC5D antibodies and engineered them as bi- and trispecific molecules. We also developed a platform for comprehensive CDR-Scanning of our lead antibody for affinity maturation, developability, and cross-species reactivity for preclinical testing.\nMethods: Antibodies against GPRC5D were isolated and formatted as GPRC5D×CD3 and GPRC5D×BCMA×CD3. These molecules were tested for in vitro and in vivo potency, cytokine release, and binding specificity. To further optimize our lead, we developed and optimized method for comprehensive CDR-Scanning where each residue across 6 CDR regions was substituted to all 19 other amino acid variants, generating 986 single residue variants. Variants were individually evaluated for expression and binding using ELISA and assessed for expression and reactivity against both human and cynomolgus GPRC5D. Beneficial substitutions (>200% wild-type binding) were combined using structure-guided and AI/ML-informed design strategies for further validation.\nResults: We identified multispecific antibodies that exhibited potent T cell-mediated cytotoxicity with picomolar potency on multiple myeloma cell lines, a large window between cell killing and cytokine release and robust tumor control against multiple myeloma xenografts in a humanized mouse model. Antibody specificity profiling confirmed high specificity binding to the intended targets, without detectable off-target interactions across the membrane proteome. Saturating mutagenesis of the CDR regions of the GPRC5D-binding moiety of the lead antibody identified 14 variants with elevated binding to the human GPRC5D >200% WT, and 10 variants with elevated binding to cynomolgus GPRC5D. Combination yielded more than 20 variants with binding >4,000% WT.\nConclusions: GPRC5D multispecific antibodies hold promise as potent and safe therapeutics for multiple myeloma. Through CDR-Scanning, we are advancing a new generation of GPRC5D antibodies with enhanced attributes, including affinity improvements, pH sensitivity, reduced polyreactivity, improved half-life, and cross-reactivity in cynomolgus for preclinical development.", "source_company": "Integral Molecular", "source_org_type": "公司", "row_number": 659, "target_meta": "GPRC5D", "MOA_meta": "双特异性抗体"}, {"drug_name": "Keytruda analog", "company": "Biocytogen", "org_type": "公司", "target": "PD-1", "modality": "inhibitor", "importance_level": "高", "total_score": 75.5, "institution_score": 75, "track_score": 85, "milestone_score": 60, "field_heat_score": 80, "bonus_score": 0, "brief_reason": "Keytruda analog为in-house anti-PD-1抗体（PD-1抑制剂），用于验证优化的人源化小鼠模型在免疫检查点抑制剂评估中的优越性。Biocytogen作为国内领先的基因编辑和抗体药物研发biotech公司，模型平台在热门IO赛道有较强技术价值，但本条记录为工具模型展示而非药物里程碑进展。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1411", "id": "OVXM_5wBX1NQZOEH-LO6", "source_drug_name": "Keytruda analog", "title": "B-NDG hIL15, FcγR KO mice: An optimized humanized model for evaluating T cell-modulating antibodies", "abstract_text": "Background:\nImmune checkpoint inhibitors targeting PD-1, PD-L1, and CTLA-4 have achieved remarkable clinical success, but preclinical validation using human immune system (HIS)-reconstituted mice remains challenging. Conventional immunodeficient models often fail to reproduce the efficacy observed in target humanized or immunocompetent mice. The poor antibody pharmacokinetics and suboptimal immune function in HIS models contribute to these discrepancies. In particular, murine innate immune cells expressing Fc gamma receptors (FcγRs) can bind therapeutic antibodies, accelerate their clearance, and induce nonspecific antibody-dependent cellular phagocytosis (ADCP), confounding efficacy assessment. Moreover, insufficient reconstitution and activation of human T cells limit the evaluation of the immune response. Human IL-15 is known to enhance T-cell survival and function following human PBMC engraftment in immunodeficient mice.\nMethods:\nTo address these limitations, Biocytogen developed B-NDG hIL15, FcγR KO mice by expressing human IL15 and knocking out the murine FcγR genes on the B-NDG background lacking mature T, B, and NK cells. Flow cytometry confirmed the absence of all four FcγRs in splenocytes. After injection of human IgG1 antibody, binding of IgG1 to CD45+ cells was detected in B-NDG mice and B-NDG hIL15 mice, but not in B-NDG hIL15, FcγR KO mice, confirming successful gene deletion. Serum human IL-15 concentration was approximately 112 pg/mL. The distribution and frequency of granulocytes, monocytes, macrophages, and dendritic cells were comparable between B-NDG hIL15 mice and B-NDG hIL15, FcγR KO mice.\nResults:\nPharmacokinetic analysis after intravenous injection of an anti-human CTLA-4 IgG1 antibody revealed that antibody clearance was fastest in B-NDG mice and slowest in B-NDG hIL15, FcγR KO mice, indicating significantly prolonged serum half-life. To evaluate antibody efficacy, human PBMCs were engrafted into B-NDG hIL15, FcγR KO mice, followed by subcutaneous implantation of three human PD-L1-high tumor cell lines (HCC827, NCI-H1975, and MDA-MB-231). Treatment with a Keytruda analog (anti-human PD-1 antibody, in-house) via intraperitoneal injection resulted in significant tumor growth inhibition across all models, demonstrating improved immunotherapeutic responsiveness.\nConclusion:\nThe huPBMC-B-NDG hIL15, FcγR KO mice provide a superior platform for evaluating the efficacy of therapeutic antibodies that modulate human T-cell functions, including immune checkpoint inhibitors.", "source_company": "Biocytogen", "source_org_type": "公司", "row_number": 692, "target_meta": "PD1", "MOA_meta": "抑制剂"}, {"drug_name": "noncovalent small molecule ligands for Brachyury", "company": "X-Chem Pharmaceuticals", "org_type": "公司", "target": "Brachyury (TBXT)", "modality": "inhibitor", "importance_level": "高", "total_score": 75.5, "institution_score": 75, "track_score": 85, "milestone_score": 60, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "靶向转录因子Brachyury（TBXT）的非共价小分子配体，针对chordoma这一罕见骨癌的驱动因子，具有突破“不可成药”靶点的潜力。X-Chem作为DEL平台头部biotech，机构实力强，赛道为热门小分子针对难靶点+罕见病未满足需求，SPR确证结合活性但仍处早期发现阶段。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3867", "id": "nFXM_5wBX1NQZOEH-LO6", "source_drug_name": "noncovalent small molecule ligands for Brachyury", "title": "DEL data-driven discovery of Brachyury (TBXT) ligands toward chordoma therapeutics", "abstract_text": "Aberrant expression of the transcription factor Brachyury (also known as TBXT) drives the growth of chordoma, a rare bone cancer with limited treatment options. While transcription factors are traditionally considered undruggable by small molecules, advances in DNA-encoded library (DEL) screening and data-driven drug discovery technologies are challenging this conventional wisdom. To discover noncovalent small molecule ligands for Brachyury, we screened X-Chem’s DEL deck comprising >150 billion diverse compounds against the Brachyury DNA-binding domain. The screen produced a rich dataset where ~73k compounds, representing >500 distinct chemical families, showed positive enrichment signal. Using X-Chem’s Chemomics platform, we translated this dataset into actionable chemical matter from three avenues: (1) off-DNA resynthesis of exact DEL-encoded structures (library compounds) that are prioritized by our DEL-to-pharmacophore (Del2Ph4) analysis workflow, (2) compounds in commercial catalogs that score highly in Machine Learning (ML) models built from the DEL data and Del2Ph4 analysis, and (3) rapid parallel synthesis of analogs of enriched library compounds using multicomponent reactions. SPR assays using full-length Brachyury protein, independently run by the Chordoma Foundation, have confirmed target-binding activity for several chemically distinct compounds. These results highlight the power of X-Chem’s drug discovery platform and offer a path forward for Brachyury-targeted chordoma therapeutics.", "source_company": "X-Chem Pharmaceuticals", "source_org_type": "公司", "row_number": 753, "target_meta": "TBXT", "MOA_meta": "抑制剂"}, {"drug_name": "[212Pb]Pb-AG1206", "company": "AlphaGen Therapeutics", "org_type": "公司", "target": "FAP", "modality": "RLT imaging agent", "importance_level": "高", "total_score": 75.5, "institution_score": 70, "track_score": 90, "milestone_score": 60, "field_heat_score": 85, "bonus_score": 3, "brief_reason": "药物靶向FAP的²¹²Pb标记大环肽放射配体疗法（RLT），属于热门的靶向α粒子治疗赛道，FAP为广谱实体瘤微环境靶点。AlphaGen作为专注RLT的中国新兴biotech获A轮融资，preclinical显示优异亲和力、肿瘤摄取、安全性和疗效，支持临床推进。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3903", "id": "bp7M_5wBZznHJdnt_W3O", "source_drug_name": "[212Pb]Pb-AG1206", "title": "[212Pb]Pb-AG1206, A novel fibroblast activation protein-targeted radioligand therapy demonstrated excellent efficacy and safety profile", "abstract_text": "Fibroblast activation protein (FAP) is highly expressed in a wide range of solid tumors, making it an attractive target for agents designed to accumulate within the tumor microenvironment. Lead-212 (²¹²Pb) is highly effective for targeted alpha therapy causing localized tumor cell killing induced by double strand DNA breaks while sparing surrounding healthy tissue. [212Pb]Pb-AG1206 is a novel macrocyclic peptide radioligand that is designed to bind to FAP selectively, and to have rapid and high tumor uptake and fast renal clearance. When conjugated with the radioisotopes 203Pb (for imaging) or ²¹²Pb (for therapy), AG1206 enables theranostic applications. Preclinical studies demonstrated excellent in vitro and in vivo properties of [212Pb]Pb-AG1206 supporting its clinical development.\nMethods: Binding affinity and selectivity were assessed using surface plasmon resonance (SPR). Cell binding and internalization were evaluated in FAP-expressing cell lines. In vivo biodistribution, antitumor efficacy, and dosimetry were performed in subcutaneous mouse cell-derived xenograft (CDX) models that express FAP.\nResults: [212Pb]Pb-AG1206 exhibited FAP-specific cellular uptake and high binding affinity in the picomolar (pM) range. It showed rapid tumor accumulation and fast clearance, and robust tumor growth inhibition with an excellent safety profile. Dosimetry studies in preclinical models demonstrated low radiation absorption in normal organs, indicating a favorable safety margin that is translatable to humans. These findings underscore FAP-targeted radioligand therapy (RLT) as a promising strategy for treating a broad spectrum of solid tumors characterized by desmoplastic microenvironments.\nConclusions: In conclusion the data support clinical development of [212Pb]Pb-AG1206 as a novel therapeutic for patients with FAP-expressing solid tumors.", "source_company": "AlphaGen Therapeutics", "source_org_type": "公司", "row_number": 1227, "target_meta": "FAP", "MOA_meta": "其他"}, {"drug_name": "BCG042", "company": "Biocytogen", "org_type": "公司", "target": "LILRB4", "modality": "inhibitor", "importance_level": "高", "total_score": 75.5, "institution_score": 75, "track_score": 80, "milestone_score": 70, "field_heat_score": 75, "bonus_score": 3, "brief_reason": "BCG042为全人源抗LILRB4 IgG1抗体，通过Fc突变增强ADCC效应，阻断LILRB4-APOE免疫抑制信号，在单核AML前临床模型中显示优于IO-202类似物的疗效。Biocytogen作为国内头部biotech平台型公司，LILRB4在AML免疫治疗赛道有一定热度，前临床体内外数据扎实且具差异化Fc增强亮点。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5379", "id": "x1XM_5wBX1NQZOEH-LK6", "source_drug_name": "BCG042", "title": "BCG042: A promising anti-LILRB4 antibody with ADCC enhancement demonstrates superior efficacy in preclinical models of monocytic AML", "abstract_text": "Monocytic acute myeloid leukemia (AML; FAB M4/M5) is an aggressive disease characterized by limited response to standard therapies, including chemotherapy and hypomethylating agent (HMA) plus venetoclax combinations. LILRB4, a validated immunosuppressive receptor highly expressed on monocytic AML blasts, drives immune evasion and tissue infiltration via APOE engagement and SHP-1/2 signaling. To overcome the limitations of current therapy, we engineered BCG042, a fully human anti-LILRB4 IgG1 antibody with an Fc mutant designed to enhance effector function and targeted clearance of AML cells. BCG042 binds to human LILRB4 with nanomolar affinity, demonstrates cross-reactivity to the cynomolgus ortholog, and exhibits high specificity within the LILRB family. Epitope binning analysis confirmed that BCG042 shares the same epitope as IO-202. BCG042 demonstrated strong binding to LILRB4-positive AML cell lines (THP-1, MV-4-11), and critically, exhibited superior inhibition of APOE-LILRB4 signaling compared to an IO-202 analog at 1 µg/mL in vitro. BCG042 mediated robust antibody-dependent cellular cytotoxicity (ADCC) against LILRB4+ AML cells, without antibody-dependent cellular phagocytosis (ADCP) or complement-dependent cytotoxicity (CDC) activity. This cytotoxicity was further amplified in an Fc-enhanced SI variant. This antibody exhibits favorable biophysical properties and developability profiles. In vivo, BCG042 induced significant dose-dependent tumor regression in a THP-1 xenograft model in B-NDG mice (dosed at 0.1, 0.5, and 1 mg/kg, Q3D×2), markedly outperforming an IO-202 analog. This potent antitumor effect was achieved with a favorable safety profile, evidenced by no body weight loss or signs of systemic toxicity. BCG042 uniquely combines targeted blockade of the LILRB4 immunosuppressive axis with potent Fc-engineered ADCC effect. This dual mechanism of action translates into superior antitumor efficacy and a favorable therapeutic window in preclinical models. These compelling data provide a strong rationale for the clinical development of BCG042 as a novel therapeutic for patients with relapsed/refractory monocytic AML.", "source_company": "Biocytogen", "source_org_type": "公司", "row_number": 1264, "target_meta": "LILRB4", "MOA_meta": "抑制剂"}, {"drug_name": "BCG045", "company": "Biocytogen", "org_type": "公司", "target": "TROP2×MUC1", "modality": "bispecific ADC", "importance_level": "高", "total_score": 75.3, "institution_score": 65, "track_score": 92, "milestone_score": 65, "field_heat_score": 85, "bonus_score": 6, "brief_reason": "BCG045为首创TROP2×MUC1双特异性ADC，通过低亲和力TROP2单价结合和MUC1-N/C junction特异性结合实现增强疗效并降低毒性。Biocytogen作为国内头部biotech平台型公司，热门双特异ADC+热门靶点赛道+创新设计亮点使其综合重要性较高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4479", "id": "WlXM_5wBX1NQZOEH-LO6", "source_drug_name": "BCG045", "title": "BCG045: A first-in-class bispecific ADC targeting TROP2 and MUC1 demonstrates promising tumor efficacy and potentially reduced toxicity in preclinical studies", "abstract_text": "Although TROP2 ADCs provide clinical benefits, they face challenges with on-target toxicity and resistance. MUC1 is another crucial biomarker in oncology. In cancer cells, MUC1 loses its normal polarity and redistributes across the cell surface and cytoplasm. It consists of two subunits: the transmembrane domain (MUC1-C), which activates key oncogenic signaling pathways, and the extracellular domain (MUC1-N), which can be shed into circulation. Both TROP2 and MUC1 are overexpressed in various epithelial tumors and are linked to poor prognosis. Furthermore, the induction of TROP2 expression can occur through the binding of galectin-3 to MUC1.\nIn this study, we developed a bispecific ADC that targets both TROP2 and MUC1, aiming to enhance efficacy while reducing target-related toxicity. To minimize the on-target toxicity associated with TROP2, we identified a TROP2 binder designed to reduce its internalization in a monovalent format with low affinity. To prevent the neutralization of antibodies/ADC by circulating shed MUC1, thereby affecting efficacy and pharmacokinetics, we developed a MUC1 binder that specifically recognizes the MUC1-N/C junction of membrane-bound MUC1 on tumor cells. This membrane-bound MUC1 binder demonstrated high specificity for MUC1 and robust affinity for both human and monkey MUC1. In tumor-bearing mouse models, the MUC1 binder exhibited an improved pharmacokinetic profile compared to benchmark antibodies, as well as strong anti-tumor efficacy. Notably, the performance of the MUC1 binder was unaffected by the presence of shed MUC1, suggesting its potential for effective therapeutic use in targeting MUC1-overexpressing tumors.\nThe TROP2×MUC1 bispecific antibody (bsAb) demonstrated broad binding capabilities across a range of tumor cell lines with varying expressions of TROP2 and MUC1. Notably, the bsAb exhibited efficient internalization in tumor cells, while also showing reduced internalization activity in TROP2 single-positive cells, which is an important feature for minimizing on-target toxicity. When conjugated with a TOP1 inhibitor (TOP1i) linker-payload, designated as BLD1102, to form BCG045, the bispecific ADC displayed potent efficacy in various patient-derived xenograft (PDX) models.\nBCG045 outperformed the benchmark ADCs in certain models, indicating its enhanced therapeutic potential. Overall, the data suggest that BCG045 could be a promising new treatment option for multiple tumors, offering improved efficacy and safety.", "source_company": "Biocytogen", "source_org_type": "公司", "row_number": 238, "target_meta": "TROP2,MUC1", "MOA_meta": "抗体偶联药物"}, {"drug_name": "DWP216", "company": "Daewoong Pharmaceutical Co., Ltd.", "org_type": "公司", "target": "TEAD1/2", "modality": "inhibitor", "importance_level": "中", "total_score": 74.5, "institution_score": 75, "track_score": 80, "milestone_score": 65, "field_heat_score": 75, "bonus_score": 3, "brief_reason": "DWP216为选择性TEAD1/2抑制剂，可逆转KRAS抑制剂耐药机制，与多种KRAS抑制剂联用显示协同效应。Daewoong为韩国TOP级药企（营收排名前列），赛道结合热门KRAS耐药与Hippo/TEAD机制热度较高，但仍处GLP毒理最终阶段，整体临床推进较早。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8858", "id": "y1XM_5wBX1NQZOEH-LG6", "source_drug_name": "G12C inhibitor", "title": "DWP216, a TEAD1/2 inhibitor, enhances efficacy of diverse KRAS inhibitors by reversing resistance mechanisms in RAS-dependent cancers", "abstract_text": "YAP-TEAD pathway plays critical in regulating cell proliferation, tissue regeneration, and organ size control, and it promotes tumor progression and metastasis in cancer. Additionally, YAP-TEAD pathway not only reinforces anti‑apoptotic signaling but also remodels the tumor microenvironment into an immune‑evasive state, representing a key mechanism driving drug resistance.DWP216 is a selective TEAD1/2 inhibitor with high selectivity over TEAD3, a TEAD form associated with renal toxicity, conferring a more favorable safety profile than pan‑TEAD inhibitors. DWP216 has demonstrated superior efficacy in NF2‑deficient tumor models and is currently in the final stages of GLP toxicology studies.KRAS mutations are a major oncogenic target, occurring in approximately 95% of pancreatic cancers and 40% of lung cancers. KRAS mutations also promote YAP-TEAD activation and, when KRAS signaling is inhibited, YAP-TEAD frequently functions as a key adaptive bypass pathway.In this study, we evaluated the combinatorial potential of DWP216 with various KRAS inhibitors. We observed that Hippo pathway gene set is upregulated in KRAS inhibitor-resistant cancer cells. DWP216 demonstrated in vitro combinatorial efficacy not only with a G12C inhibitor but also with a G12D inhibitor and a pan-RAS inhibitor. Resistance-associated mechanisms to KRAS inhibition such as activation of MAPK signaling and the PI3K/mTOR pathway, were observed in KRAS inhibitor-resistant cancer cells. Treatment with DWP216 reduced Hippo pathway activation and restored sensitivity to KRAS inhibition by reversing these compensatory mechanisms. Combination treatment with DWP216 and KRAS inhibitors also increased pro-apoptotic markers. In vivo CDX models harboring KRAS mutations showed strong combinatorial activity of DWP216 with KRAS inhibitor. In conclusion, DWP216 can be effectively combined with various KRAS inhibitors and may be extendable as a combination strategy against RAS-dependent cancers such as PDAC.", "source_company": "Daewoong Pharmaceutical Co., Ltd.", "source_org_type": "公司", "row_number": 18, "target_meta": "TEAD1,TEAD2", "MOA_meta": "抑制剂"}, {"drug_name": "ZE00-0388", "company": "Expert Systems, Inc.", "org_type": "公司", "target": "PTPN2/1", "modality": "inhibitor", "importance_level": "中", "total_score": 74.5, "institution_score": 65, "track_score": 85, "milestone_score": 75, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "ZE00-0388为高选择性口服小分子PTPN2/1抑制剂，通过解除免疫细胞内制动增强IFN-γ信号和T细胞杀伤，与anti-PD-1联用显示协同抗瘤效应。机构为AI驱动药物发现加速器而非头部药企，得分中等；赛道为新型IO靶点+小分子抑制剂热度高，preclinical数据强包括显著疗效、安全窗宽和清晰PK/PD，综合潜力较高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9608", "id": "31XM_5wBX1NQZOEH-LK6", "source_drug_name": "anti-mPD-1", "title": "Efficacy, in vivo safety, and PK/PD studies for novel, oral, highly selective PTPN2/1 inhibitor (ZE00-0388)", "abstract_text": "PTPN2 inhibition is a novel immuno-oncology approach: by releasing an intracellular “brake” it increases cytokine responsiveness (e.g., IFN-γ/JAK-STAT), boosts antigen presentation, and enhances T-cell cytotoxicity, helping to overcome immune evasion in tumors resistant to PD-1 blockade.\nOur development candidate ZE00-0388 demonstrates potential best-in-class profile: Nanomolar potency with high selectivity for PTPN2/1 over other phosphatases, predictable PK/PD with sustained exposure above EC50, and proven target engagement. ZE00-0388 shows favorable bioavailability in all species, with best translation expected from dog to human.\nThe combination of anti-mPD-1 and ZE00-0388 exhibited remarkable dose-dependent anti-tumor efficacy against the subcutaneous MC38 colon model. Solo treatments with ZE00-0388 demonstrated tumor growth inhibition of 81% and in combination with anti-mPD-1 complete regression of tumor in 50% of animals. ZE00-0388 has a very favorable safety profile with tolerated doses significantly above pre-clinical proof-of-concept efficacious doses, which indicates that ZE00-0388 should have a very broad therapeutic window.", "source_company": "Expert Systems, Inc.", "source_org_type": "公司", "row_number": 49, "target_meta": "PTPN2,PTP1B", "MOA_meta": "抑制剂"}, {"drug_name": "MC001", "company": "Medicovestor, Inc.", "org_type": "公司", "target": "FRα", "modality": "ADC", "importance_level": "中", "total_score": 74.5, "institution_score": 65, "track_score": 85, "milestone_score": 75, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "MC001为靶向FRα的创新型chemoimmunotherapy ADC，结合ADCC与MMAE payload杀伤增殖及静止期肿瘤细胞，体现下一代ADC机制。Medicovestor为美国新兴biotech，ADC热门赛道+胰腺癌高未满足需求+IND-enabling阶段+Orphan Drug Designation及强preclinical数据支撑较高潜力。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11050", "id": "d1XM_5wBX1NQZOEH-LG5", "source_drug_name": "MC001", "title": "MC001: A novel chemoimmunotherapy antibody drug conjugate for treating folate receptor alpha expressing pancreatic cancer", "abstract_text": "Background: The prognosis for patients with advanced pancreatic ductal adenocarcinoma (PDAC) remains dismal, even with intensive multi-agent chemotherapy. Many patients are also unable to tolerate these regimens due to systemic toxicity. Folate receptor alpha (FRα), overexpressed in up to 80% of PDAC cases, is associated with poor clinical outcomes and represents a promising therapeutic target. MC001 is a novel chemoimmunotherapy antibody-drug conjugate (ADC) designed to target FRα and to harness both payload-mediated and antibody-mediated cytotoxic mechanisms. Here, we evaluated the preclinical efficacy and safety of MC001 in FRα-expressing PDAC models.\nMethods: A high-affinity FRα-specific antibody was isolated from a human v-gene phage display library and engineered into a dimeric, tetravalent IgG1 antibody (ADoBind) through a disulfide bond generated by an S444C mutation. MC001 was synthesized by lysine-based conjugation of the ADoBind antibody to monomethyl auristatin E (MMAE) via an enzyme-cleavable linker, achieving an average drug-to-antibody ratio of 6.\nResults: The tetravalent ADoBind antibody demonstrated higher avidity to FRα than its monomeric counterpart and mediated robust antibody-dependent cellular cytotoxicity (ADCC) against FRα-positive SU.86.86 human pancreatic cancer cells using human peripheral blood mononuclear cells (PBMCs), while complement-dependent cytotoxicity was not detected. In a SCID mouse xenograft model co-administered with human PBMCs, ADoBind antibodies induced potent ADCC in vivo and achieved significant tumor growth inhibition. In a single-dose PDAC xenograft study, ADoBind-MMAE ADC (MC001) produced approximately fivefold greater tumor inhibition than its monomeric ADC counterpart at equivalent molar dosing. Tumor suppression was durable, persisting beyond 30 days after a single injection, and resulted in improved overall survival. Single-dose toxicology studies in SD rats and cynomolgus monkeys showed that MC001 was well tolerated, with no significant systemic toxicities. Only transient, mild neutropenia was observed at the highest dose level (12 mg/kg). The serum half-life of MC001 was 5.4 days following a single 3 mg/kg dose, supporting favorable pharmacokinetics for intermittent dosing.\nConclusions: Up to 40% of ADC payloads may be released extracellularly before cellular internalization, revealing an opportunity to exploit the intrinsic antitumor activity of the antibody moiety. By combining antibody-mediated immune cytotoxicity with targeted delivery of a payload, MC001 represents a next-generation chemoimmunotherapy ADC capable of killing both proliferating and quiescent (G₀-phase) tumor cells. These results in preclinical models support advancement of MC001 and the ADoBind platform, which are currently progressing through IND-enabling development.", "source_company": "Medicovestor, Inc.", "source_org_type": "公司", "row_number": 139, "target_meta": "FOLR1", "MOA_meta": "抗体偶联药物"}, {"drug_name": "GS24-B047", "company": "Changchun GeneScience Pharmaceutical Co., Ltd", "org_type": "公司", "target": "DLL3", "modality": "TCE", "importance_level": "中", "total_score": 74.5, "institution_score": 65, "track_score": 85, "milestone_score": 75, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "GS24-B047为靶向DLL3的T-cell engager（TCE），集成共刺激信号以增强T细胞持久性和抗SCLC活性，区别于Tarlatamab的独特表位和降低T细胞耗竭。机构为国内知名生物制药企业（生长激素龙头），DLL3 TCE在SCLC领域热度高，preclinical数据强劲包括体外/体内优效和IND前准备，但非头部MNC/biotech导致综合评分中位。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9591", "id": "WlXM_5wBX1NQZOEH-LG5", "source_drug_name": "GS24-B047", "title": "GS24-B047, a potential best-in-class DLL3-targeting T-cell engager with integrated costimulatory signal, for the treatment of small cell lung cancer", "abstract_text": "Background: Small cell lung cancer (SCLC) remains an aggressive malignancy with limited therapeutic options and poor prognosis, particularly in the relapsed/refractory settings. DLL3, a tumor-associated antigen highly expressed on SCLC cells with minimal expression in normal tissues, represents a promising therapeutic target. While T-cell engagers (TCEs) targeting DLL3 and CD3, such as Tarlatamab, have demonstrated clinical activity, maintaining T-cell function in the tumor microenvironment remains challenging, and improvements in progression-free survival (PFS) have been limited. GS24-B047 is a novel DLL3-targeting TCE that incorporates a proprietary costimulatory signal designed to enhance T cell activation and persistence, with the potential to improve clinical efficacy in SCLC patients.\nMethods: Binding activity and specificity of GS24-B047 to DLL3, CD3, and the costimulatory target were characterized by surface plasmon resonance (SPR), Octet biosensor, and flow cytometry. In vitro functional activity was assessed in co-culture assays with human PBMCs and DLL3-expressing SCLC cell lines, measuring T cell activation, cytokine release, and cytotoxicity. In vivo anti-tumor efficacy was evaluated in SCLC cell-derived xenograft (CDX) models with human immune system reconstitution.\nResults: GS24-B047 bound to DLL3 with sub-nanomolar affinity, recognizing a distinct, more membrane-proximal epitope as compared to Tarlatamab, and effectively mediated simultaneous engagement of DLL3 on tumor cells and CD3 on T cells. In vitro, GS24-B047 induced T cell activation, proliferation, and cytokine secretion, and exhibited potent cytotoxicity against DLL3-expressing SCLC cell lines (with EC50 values in the picomolar range). GS24-B047 demonstrated a favorable therapeutic index with a high ratio of tumor cell killing to IL-6 release. The integrated costimulatory signal reduced markers of T-cell exhaustion as compared to a benchmark DLL3xCD3 TCE, supporting a more sustained T-cell response. In vivo, GS24-B047 treatment resulted in significant and durable tumor regression in multiple CDX models of SCLC, showing enhanced anti-tumor activity when compared to clinical benchmarks.\nConclusion: GS24-B047 is a novel DLL3-targeting TCE with integrated costimulation that promotes potent and sustained anti-tumor immunity in preclinical SCLC models. Collectively, our data support GS24-B047 as a potential therapeutic candidate for SCLC and warrant further evaluation in IND-enabling studies.", "source_company": "Changchun GeneScience Pharmaceutical Co., Ltd\nChangchun GeneScience Pharmaceutical Co., Ltd.", "source_org_type": "公司", "row_number": 140, "target_meta": "DLL3", "MOA_meta": "其他"}, {"drug_name": "JMKX007129", "company": "Shanghai Jeyou Pharmaceutical Co., Ltd.", "org_type": "公司", "target": "AR-NTD", "modality": "inhibitor", "importance_level": "中", "total_score": 74.5, "institution_score": 65, "track_score": 85, "milestone_score": 75, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "JMKX007129靶向AR N-terminal domain (NTD)，克服AR LBD突变导致的耐药，属于下一代AR抑制剂，preclinical数据强劲包括体外体内活性、选择性、PK及与现有AR药协同。机构为国内创新药企非头部，赛道热门（mCRPC耐药克服+AR-NTD新机制），IND-enabling阶段进展良好，综合潜力较高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8831", "id": "Ap7M_5wBZznHJdnt_W7O", "source_drug_name": "JMKX007129", "title": "JMKX007129 is a next generation of androgen receptor inhibitor targeting N-terminal domain for the treatment of metastatic castration-resistant prostate cancers", "abstract_text": "Background: Androgen receptor ligand binding domain (AR LBD) mutations are one of the key factors leading to resistance to AR inhibitors or degraders in castration-resistant prostate cancer (CRPC). As a result, inhibitors targeting other domains of AR, such as the NTD, have become a major focus in current drug development efforts to overcome this resistance. However, the clinical development of Anitens-based AR-NTD inhibitors has encountered setbacks due to insufficient activity and selectivity. Therefore, there is an urgent need to develop AR-NTD inhibitors with higher potency, improved selectivity, and enhanced safety profiles.\nMethods: Based on the core structure of Anitens, we conducted rational design and obtained the lead compound JMKX007129. A comprehensive suite of in vitro and in vivo characterizations was subsequently performed. These evaluations included assessments of its target binding affinity, mechanism of action, in vitro and in vivo efficacy, pharmacokinetic and toxicological profiles, as well as its combination effects with existing AR inhibitors and degraders.\nResults: Compound JMKX007129 demonstrated excellent in vitro and in vivo activity and selectivity. Cellular Thermal Shift Assay (CETSA) confirmed that JMKX007129 simultaneously engages both full-length AR (in LnCap cells) and the splice variant AR-V7 (in 22RV1 cells). Reporter gene and qPCR assays demonstrated that JMKX007129 effectively (EC50≈20 nM) modulates the transcription of downstream genes of both AR and AR-V7. It potently inhibited the proliferation of AR-positive prostate cancer cells, exhibiting a selectivity window of approximately 20-fold over AR-negative cells. JMKX007129 displayed favorable pharmacokinetic properties in mice, rats, and dogs, which translated into robust in vivo antitumor efficacy. Significant activity was observed in models sensitive to AR inhibitors (LnCap) as well as in those with acquired resistance (VCap, 22RV1), accompanied by a favorable tolerability profile. Finally, JMKX007129 exhibited a synergistic anti-proliferative effect in combination with AR inhibitors or degraders in 22RV1 cells.\nConclusions: In summary, we have successfully developed JMKX007129, a novel small-molecule compound targeting the AR-NTD. Preclinical studies demonstrate that JMKX007129, both as a monotherapy and in combination with AR inhibitors or degraders, exhibits promising in vitro and in vivo efficacy and a favorable safety profile, indicating its potential to overcome resistance mediated by AR LBD mutations. IND-enabling studies for JMKX007129 are currently underway.", "source_company": "Shanghai Jeyou Pharmaceutical Co., Ltd.", "source_org_type": "公司", "row_number": 165, "target_meta": "not available", "MOA_meta": "抑制剂"}, {"drug_name": "Doxitinib", "company": "Genuine Biotech Co., Ltd.", "org_type": "公司", "target": "EGFR", "modality": "inhibitor", "importance_level": "中", "total_score": 74.5, "institution_score": 65, "track_score": 85, "milestone_score": 75, "field_heat_score": 80, "bonus_score": 2, "brief_reason": "Doxitinib为奥希替尼的氘代类似物，靶向EGFR，保留强效抑制活性并显著降低毒性代谢物形成，具有更好安全性及潜在高剂量耐受优势。机构为国内具有一定知名度的biotech（曾推出Azvudine），赛道为热门EGFR NSCLC领域，已有I/II期临床数据及脑转移活性，拟推进联合治疗试验，故综合热度与里程碑价值较高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4018", "id": "aZ7ECZ0BZznHJdntvNYd", "source_drug_name": "Doxitinib", "title": "Azvudine combined with Doxitinib, a potential therapy for EGFRm+ NSCLC", "abstract_text": "Osimertinib, a third-generation EGFR tyrosine kinase inhibitor (EGFR-TKI), is the current standard first-line therapy for patients with EGFR-mutant non-small cell lung cancer (NSCLC). Although Osimertinib significantly improves progression-free survival (PFS), some patients exhibit intrinsic resistance, and nearly all eventually develop acquired resistance.\nDoxitinib, a deuterated analog of Osimertinib, retains potent EGFR inhibitory activity while significantly reducing the formation of toxic metabolites by up to 80% in preclinical models, suggesting an improved safety profile and the potential for enhanced therapeutic efficacy through higher tolerated dosing. In a phase 1/2 clinical study (ChiCTR2000039281), Doxitinib demonstrated a favorable safety profile without dose-limiting toxicities (DLTs) across doses ranging from 20 to 240 mg daily in patients previously treated with EGFR TKIs. Encouraging clinical activity was observed, including antitumor responses in brain metastases. The ongoing expansion phase is further evaluating Doxitinib in EGFRm⁺ NSCLC patients naïve to EGFR-TKI therapy.\nTo overcome resistance and enhance antitumor efficacy, we combined Doxitinib with Azvudine (FNC), a fluorinated nucleoside analog with dual antitumor mechanisms. FNC inhibits tumor cell proliferation via its active triphosphate metabolite, which incorporates into DNA or RNA to disrupt nucleic acid synthesis, induce replication stress, and arrest tumor growth. Moreover, FNC modulates the tumor immune microenvironment (TIME) by suppressing myeloid-derived suppressor cell (MDSC) differentiation and infiltration while enhancing CD8⁺ T cell and NK cell activation, thus shifting the TIME from immunosuppressive to immunoreactive—an essential factor in overcoming EGFR-TKI resistance. In vitro, the combination of FNC and Doxitinib additively inhibited the proliferation of NCI-H1975 (EGFR L858R/T790M/C797S) triple-mutant NSCLC cells. In vivo, the combination achieved superior tumor growth inhibition compared to either monotherapy in the NCI-H1975 (EGFR L858R/T790M) xenograft model.\nCollectively, these findings suggest that the combination of FNC and Doxitinib represents a promising therapeutic strategy to enhance efficacy and overcome acquired resistance in EGFRm⁺ NSCLC. Based on these preclinical and clinical findings, a phase 1/2 clinical trial will be initiated to evaluate the safety and efficacy of this combination therapy in EGFR-mutant NSCLC patients.", "source_company": "Genuine Biotech Co., Ltd.", "source_org_type": "公司", "row_number": 248, "target_meta": "EGFR", "MOA_meta": "抑制剂"}, {"drug_name": "ATS1002", "company": "AbTis Co., Ltd", "org_type": "公司", "target": "CLDN18.2×HER2", "modality": "bispecific ADC", "importance_level": "中", "total_score": 74.5, "institution_score": 70, "track_score": 95, "milestone_score": 50, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "ATS1002为基于eKiH平台的CLDN18.2×HER2双特异性ADC，旨在克服胃癌靶点异质性，利用热门靶点CLDN18.2和HER2及ADC+双抗赛道高热度。机构为韩国中小型biotech（Dong-A ST子公司），preclinical阶段有体外强效数据但无临床里程碑，得分中等偏上。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5399", "id": "V1XM_5wBX1NQZOEH-LS6", "source_drug_name": "ATS1002", "title": "Overcoming target heterogeneity in gastric cancer with an eKiH-engineered CLDN18.2×HER2 bispecific ADC", "abstract_text": "Background: Target heterogeneity, mosaic and cluster expression of CLDN18.2 and HER2 is common in gastric cancer (GC) and undermines the efficacy of single-antigen therapies. We previously developed DA3501 (AT-211), a CLDN18.2-targeting ADC currently advancing toward Phase 1 evaluation. The DA3501 antibody clone demonstrates enhanced affinity and internalization compared with zolbetuximab. To more comprehensively address heterogeneous tumors, we engineered a CLDN18.2×HER2 bispecific ADC built on Dong-A ST BsAb platform incorporating an enhanced knob-into-hole (eKiH) interface to improve heavy-chain pairing fidelity and bispecific assembly.\nMethods: Antibody discovery and optimization yielded lead clones for CLDN18.2 and HER2 with improved binding and internalization. Bispecifics were assembled using Dong-A ST BsAb platform. Conjugation to monomethyl auristatin E (MMAE), exatecan (a topoisomerase-I inhibitor), or dual-payload configurations was performed using site-selective chemistry. Target prevalence and co-expression were evaluated in human GC using single-cell RNA sequencing (scRNA-seq) of tumor specimens and multiplex immunohistochemistry (mIHC) on tissue microarrays (TMAs). Immune correlates were analyzed to assess combinatorial potential with immune checkpoint inhibitors (ICIs).\nResults: scRNA-seq revealed CLDN18.2 and HER2 expression in mutually exclusive as well as co-expressing tumor cell subsets, corroborated by mIHC showing intra-tumoral mosaic and clustered patterns. The DA3501 anti-CLDN18.2 clone exhibited superior binding kinetics and internalization versus zolbetuximab. ATS1002 retained high-affinity binding to both targets and demonstrated efficient internalization in dual-positive and single-positive (CLDN18.2 or HER2) models, supporting a “catch-all” approach for heterogeneous lesions. ADCs conjugated with MMAE, exatecan, or dual payloads showed potent in vitro cytotoxicity across CLDN18.2-high, HER2-high, and co-expressing GC lines. Immune-correlative analyses indicated potential synergy with ICIs in tumors exhibiting activated T-cell and myeloid signatures.\nConclusions: This BsAb is a rationally engineered CLDN18.2×HER2 bispecific ADC designed to overcome target heterogeneity in GC. Together with the DA3501 program, it broadens therapeutic coverage of CLDN18.2/HER2-expressing tumors and combination-strategy studies, including ICI co-therapy.", "source_company": "AbTis Co., Ltd", "source_org_type": "公司", "row_number": 255, "target_meta": "CLDN18.2,HER2", "MOA_meta": "抗体偶联药物"}, {"drug_name": "ALG-094295", "company": "Aligos Belgium BV", "org_type": "公司", "target": "PD-L1", "modality": "inhibitor", "importance_level": "中", "total_score": 74.5, "institution_score": 65, "track_score": 85, "milestone_score": 75, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "ALG-094295为口服小分子PD-L1抑制剂，通过促进PD-L1二聚化、内化和降解实现新型机制阻断PD-1/PD-L1通路，比抗体具有潜在优势。Aligos为专注肝病和病毒领域的国外中小型biotech公司，赛道为热门口服小分子PD-(L)1抑制剂，preclinical数据强劲显示优于同类化合物并等效于抗体，综合热度较高但尚未临床。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5269", "id": "J57M_5wBZznHJdnt_W3O", "source_drug_name": "ALG-094295", "title": "Preclinical Characterization of ALG-094295, a highly potent and orally bioavailable small molecule PD-1/PD-L1 inhibitor targeting dimerization, internalization and degradation of PD-L1", "abstract_text": "Background: PD-1/PD-L1 antibody-based therapies have demonstrated tremendous success in the treatment of a variety of cancers. However, these antibody drugs are associated with several disadvantages, such as weak tumor penetration, immune-related adverse events and emergence of anti-drug antibodies. Here, we report the discovery and characterization of ALG-094295 as a highly potent and orally bioavailable small molecule PD-1/PD-L1 inhibitor that binds to PD-L1 and promotes PD-L1 dimerization, internalization and degradation, offering a different mechanism of action with potential advantages over PD-1/PD-L1 antibody therapeutics.\nMethods: The interaction of PD-1/PD-L1 and PD-L1 dimerization were assessed by AlphaLISA®. Cellular activity was measured using PD-1 expressing Jurkat NFAT luciferase T cells and CHO-hPD-L1 cells. In vivo PD-L1 target engagement, tumor growth inhibition and tumor infiltration of T-cells were assessed in a humanized-PD-L1 MC38 subcutaneous tumor mouse model. In vitro ADME tox profile was established using standard assays. Pharmacokinetic (PK) studies were performed with rat, dog and cynomolgus monkey.\nResults: ALG-094295 demonstrated inhibition of PD-1/PD-L1 interaction at sub-nanomolar concentrations and induced PD-L1 dimerization.  In vitro studies showed that ALG-094295 activated T cells with approximately ten times greater potency compared to INCB086550, an orally administered small molecule PD-L1 inhibitor that has demonstrated clinical responses in a phase I trial. Furthermore, treatment of CHO-hPD-L1 cells with ALG-094295 resulted in internalization and reduction of PD-L1 protein levels. In ex vivo human PBMC assays, ALG-094295 demonstrated PD-L1 target engagement, T cell activation and immune cell mediated tumor cell killing. In a humanized PD-L1 MC38 mouse model, a single oral dose of ALG-094295 (5 mg/kg) achieved PD-L1 target engagement comparable to INCB086550 (150 mg/kg PO). Daily oral dosing of ALG-094295 (50 or 150 mg/kg) in humanized PD-L1 MC38 mice over 21 days resulted in tumor growth inhibition equivalent to twice-weekly administration of durvalumab (10 mg/kg IV), with tumor size correlating with increased CD8⁺ T-cell infiltration. ALG-094295 demonstrated no in vitro liabilities for CYP450 inhibition or induction mediated drug-drug interactions, off target toxicity, cardiovascular safety, or genotoxicity. Preclinical in vivo PK data suggests once-daily oral dosing is feasible in humans.\nConclusion: ALG-094295 is a highly potent and orally bioavailable small molecule PD-1/PD-L1 inhibitor that promotes PD-L1 dimerization, internalization and degradation. ALG-094295 has the potential to overcome some limitations of antibody-based therapies due to potent PD-L1 blockade, oral delivery and novel mechanism of action.", "source_company": "Aligos Belgium BV", "source_org_type": "公司", "row_number": 261, "target_meta": "PDL1", "MOA_meta": "抑制剂"}, {"drug_name": "KT-300", "company": "Kayak Therapeutics, Inc.", "org_type": "公司", "target": "TRIM7", "modality": "inhibitor", "importance_level": "中", "total_score": 74.5, "institution_score": 65, "track_score": 85, "milestone_score": 75, "field_heat_score": 80, "bonus_score": 6, "brief_reason": "KT-300为首创TRIM7小分子抑制剂，针对RTK/KRAS通路下游新靶点，提供mutation-agnostic广谱活性并克服KRASi耐药。机构为早期美国biotech（种子轮阶段），赛道结合热门KRAS相关耐药与新型E3 ligase抑制机制具较高热度，preclinical数据扎实包括多种模型TGI及联合增强。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8897", "id": "2Z7M_5wBZznHJdnt_W3O", "source_drug_name": "KT-300", "title": "TRIM7 inhibition blocks RTK/RAS pathway driven tumor proliferation independent of mutation and in the setting of KRASi resistance", "abstract_text": "Most cancer patients experiencing clinical benefit from targeted therapies in RTK-KRAS driven cancers develop acquired resistance (AR) and relapse. The mechanism of resistance in patients who initially respond to monoallelic KRAS G12C/G12D inhibitors is dominated by the accumulation of new mutations in KRAS itself, followed by mutations downstream in the MAP kinase pathway. Therapeutics that more broadly target this pathway, like the multi-KRAS isoform inhibitor daraxonrasib, offer promise in less common mutations (e.g., KRAS G12X/Q61X). However, the tolerability of KRASi combinations has been a concern, and it is unclear whether similar resistance mechanisms will arise in multi-KRASi treated patients, as has been seen in monoallelic-KRASi treated patients. To identify novel approaches for complex or resistant RTK-KRAS driven cancers, we generated a murine CRC KRAS(G12D) AR model and through transcriptional/proteomic analysis, identified the E3 ubiquitin ligase TRIM7 as a putative driver of resistance. TRIM7 is downstream in the RTK-KRAS pathway and is upregulated in KRAS mutant and MSI-high tumors, resulting in (1) aberrant cell proliferation through ubiquitination and stabilization of RACO-1 and activated cJun/AP1 transcription, and (2) dysregulated IFN responsiveness through ubiquitination and degradation of MAVS and STING. TRIM7 is not a known mutated oncogene; rather, its hyperactivation is a byproduct of increased RTK-KRAS signaling due to upstream amplifications or mutations. We developed a highly potent and selective TRIM7 small-molecule inhibitor (KT-300) and showed it directly disrupts the ubiquitination and stability of RACO-1, resulting in decreased phosphorylation of cJun and STAT3, and altered transcription of cJun/AP1 targets. KT-300 reduced ubiquitination of MAVS, resulting in MAVS accumulation, and restored STING signaling in tumor cells where STING was impaired due to TRIM7 overexpression. KT-300 induced significant TGI in a range of KRAS/NRAS mutant tumor models (G12X, G13X, and Q61X) and in cell lines with amplification or mutation of EGFR or MAP kinase. TRIM7 specificity was confirmed using inactive enantiomers, which did not induce TGI. In vivo, monotherapy KT-300 delayed the growth of human KRAS-mutant NSCLC, CRC, and PDAC tumor xenograft and PDX models. TRIM7i-induced anti-tumor activity was enhanced in combination with concurrent KRAS inhibition, and KT-300 monotherapy delayed tumor growth in mice that developed resistance and progressed on KRAS inhibitors. TRIM7 inhibition via KT-300 may offer broad, mutation-agnostic activity in RTK-KRAS driven cancers. This represents a novel “pan-RTK-KRAS pathway inhibition” strategy that could extend efficacy to complex mutational backgrounds not addressed by current KRAS inhibitors, including in patients who have developed resistance to existing RTK-KRAS targeted therapies.", "source_company": "Kayak Therapeutics, Inc.", "source_org_type": "公司", "row_number": 275, "target_meta": "TRIM7", "MOA_meta": "抑制剂"}, {"drug_name": "bispecific antibody combinations targeting 4-1BB and HER2", "company": "Light Chain Bioscience – Novimmune SA", "org_type": "公司", "target": "4-1BB (肿瘤选择性激活，依赖HER2)", "modality": "bispecific antibody", "importance_level": "中", "total_score": 74.5, "institution_score": 70, "track_score": 85, "milestone_score": 65, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "药物为4-1BB/HER2双抗组合策略，实现肿瘤微环境特异性4-1BB激活以增强T细胞抗肿瘤活性，机构为专注双抗的瑞士临床阶段biotech（有历史抗体获批及临床项目），赛道热门（双抗+4-1BB共刺激），但仍处preclinical体外/体内模型阶段无临床数据。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4510", "id": "7lXM_5wBX1NQZOEH-LC5", "source_drug_name": "bispecific antibody combinations targeting 4-1BB and HER2", "title": "Tumor-selective activation of 4-1BB receptor via bispecific antibody combinations", "abstract_text": "INTRODUCTION:\n4-1BB (CD137) is an inducible co-stimulatory molecule that plays crucial roles in immune activation. Upon ligand binding, 4-1BB forms trimeric signaling complexes triggering receptor activation. However, therapeutic monoclonal antibodies targeting 4-1BB often face challenges due to peripheral toxicities arising from systemic receptor activation. To address this, bispecific antibodies (bsAbs) have been developed to selectively activate 4-1BB in a tumor-associated antigen (TAA)-dependent manner. This report investigates whether a combination of bsAbs, pairing 4-1BB and TAA targeting arms, can further enhance 4-1BB clustering and activation in the tumor microenvironment.\nMETHODS:\nA panel of Fc-silent bsAbs targeting different domains on 4-1BB and HER2 were generated and tested in combination for optimal 4-1BB signaling. For that purpose, 4-1BB reporter cells were co-cultured with HER2-expressing tumor cells. Functional in vitro assays were conducted using primary human T cells isolated from peripheral blood mononuclear cells to assess cytokine production and their tumoricidal activity. In vivo efficacy was evaluated in PBMC-engrafted NOG mice inoculated with JIMT-1, a HER2-expressing tumor cell line.\nRESULTS:\nThe simultaneous binding of two bsAbs to the same epitope on 4-1BB, while targeting distinct epitopes on HER2, markedly enhances 4-1BB signaling, compared to the single bsAbs. 4-1BB signaling triggered by the bsAbs is driven by HER2 expression, with strong IL-2 release observed only in the presence of HER2-positive cells. In JIMT-1 xenograft models, combination of the bsAb pair with a T cell engager (TCE) resulted in superior antitumor activity and enhanced CD4⁺ and CD8⁺ T-cell infiltration within the tumor microenvironment, compared to either single bsAb plus TCE or the TCE alone.\nCONCLUSIONS:  This study introduces a novel bsAb combination strategy that amplifies TAA-driven activation of 4-1BB⁺ T cells and may unlock similar opportunities to other TNFR superfamily targets such as OX40 and CD40.", "source_company": "Light Chain Bioscience – Novimmune SA", "source_org_type": "公司", "row_number": 296, "target_meta": "4-1BB", "MOA_meta": "双特异性抗体"}, {"drug_name": "a potent AR degrader", "company": "AnHorn Medicines Co., Ltd.", "org_type": "公司", "target": "AR", "modality": "degrader", "importance_level": "中", "total_score": 74.5, "institution_score": 55, "track_score": 90, "milestone_score": 75, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "靶点为AR，通过CRBN介导的PROTAC机制实现靶向降解，有效克服CRPC中AR突变耐药，AI辅助设计并在体外/体内模型显示强效抗肿瘤活性。AnHorn为2020年成立的台湾新兴AI驱动biotech，获数千万美元A轮融资，PROTAC赛道+AR热门靶点热度高，但机构非头部MNC，整体处于preclinical强展示阶段。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8707", "id": "FFXM_5wBX1NQZOEH-LK6", "source_drug_name": "a potent AR degrader", "title": "Rational design of potent androgen receptor degraders via AI-assisted molecular modeling and validation of anti-tumor efficacy in prostate cancer", "abstract_text": "The androgen receptor (AR) plays a central role in the progression of prostate cancer, and its sustained signaling remains a major challenge in castration-resistant prostate cancer (CRPC). Targeted protein degradation of the AR offers a promising therapeutic strategy to overcome therapeutic resistance that limits the efficacy of current AR antagonists. To rationally design novel AR degraders, we employed AnHorn’s proprietary AIMCADD (Artificial Intelligence-bio-Informatic-MedChem-Computer-Aided Drug Design) platform to predict the three-dimensional binding conformations between the AR ligand-binding domain (AR-LBD) and CRBN E3 ligase. Molecular dynamics (MD) simulations were used to calculate binding free energies and identify the most stable AR-CRBN ternary complex. Based on this complex, the binding conformations of AR-LBD and CRBN warheads were obtained via molecular docking, followed by AI-assisted linker generation using AIMLinker, a deep neural network-based algorithm, to construct a virtual library of degrader candidates. Molecular docking and dynamic simulations were further applied to evaluate ternary complex stability and binding affinity, from which a subset of top-ranked candidates were selected for experimental validation. Lead candidates effectively induced AR degradation in LNCaP, 22Rv1, and VCaP cells. Notably, these degraders also retained activity against clinically relevant AR mutants frequently observed in CRPC patients, including L702H, T878A, H875Y, W742C, and F877L. The degradation was abolished by co-treatment with the proteasome inhibitor MG132, confirming a ubiquitin-proteasome-dependent mechanism. Direct binding of the lead compound to AR was further verified by drug affinity responsive target stability (DARTS) assay. Quantitative RT-PCR analysis revealed a marked downregulation of AR downstream targets, KLK3 (PSA), suggesting the loss of AR transcriptional activity. In cell viability assays, the most potent compound selectively suppressed proliferation of AR-positive prostate cancer cells, with minimal cytotoxicity in normal cells. In xenograft animal models, once daily administration significantly reduced tumor volume and prostate specific antigen (PSA) level in plasma without observable systemic toxicity. In summary, through AI-assisted molecular design and computational screening, we developed a potent AR degrader that efficiently induces proteasome-dependent AR degradation, suppresses AR transcriptional activity, and exhibits robust anti-tumor efficacy in vivo. These results highlight a promising therapeutic approach for advanced prostate cancer through targeted AR degradation.", "source_company": "AnHorn Medicines Co., Ltd.", "source_org_type": "公司", "row_number": 505, "target_meta": "AR", "MOA_meta": "降解剂"}, {"drug_name": "GCAR CD20 LVV", "company": "EXUMA Biotech Corp", "org_type": "公司", "target": "CD20", "modality": "other", "importance_level": "中", "total_score": 74.5, "institution_score": 65, "track_score": 85, "milestone_score": 75, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "GCAR CD20 LVV为CD3靶向慢病毒载体（LVV）介导的in vivo CAR生成平台，针对CD20实现B细胞耗竭，无需ex vivo制造或淋巴耗竭化疗。EXUMA Biotech作为专注CAR-T和基因疗法的临床阶段中小型biotech公司，平台创新性强、NHP模型显示持久B细胞清除和良好安全性，赛道为热门in vivo CAR领域，故综合评分较高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10433", "id": "U1XM_5wBX1NQZOEH-LO6", "source_drug_name": "GCAR CD20 LVV", "title": "Anti-tumor activity in humanized xenograft models and B-cell aplasia in non-human primates with a novel CD3-directed in vivo gene-modifying CAR (GCAR) lentivector encoding chimeric antigen receptors and a cellular fitness-enhancing co-stimulatory protein", "abstract_text": "Introduction: An in vivo gene-modifying CAR (GCAR) platform has been developed to mitigate known clinical and logistical challenges with traditional ex-vivo manufactured CAR-T products. The GCAR platform incorporates an NHP/human reactive CD3-targeted lentivector (LVV) with complement resistant fusogen that encodes CD3zeta based CARs and a compact synthetic costimulatory protein (FD) optimized for proliferation, persistence, and cytotoxicity. The ability of GCAR LVVs to elicit potent, specific and persistent cytotoxicity towards target cells was evaluated in vitro and in humanized and non-human primate models. In M. nemestrina, GCAR CD20 CAR was evaluated for B-cell depletion compared to LVVs encoding conventional 41BB CARs without FD.\nMethods: Anti-CD19 or anti-CD20 LVV’s manufactured from 6L and 25L scales were characterized for CD3 reactivity in M. nemestrina and human PBMC in vitro and in vivo. Serum complement sensitivity and activation assays were used to characterize GCAR LVVs (encoding anti-CD20 CAR and FD) against human and NHP sera and CD3 positive lymphocytes. Escalating doses (IV or IN) of purified LVV’s were evaluated in the NHPs. B-cells were quantified by flow cytometry and safety by clinical chemistry, hematology, and physical assessments.\nResults: Exposure of human or nemestrina PBMC to GCAR LVVs resulted in dose and target-dependent cell lysis with rapid tumor clearance in Raji-Luc disseminated PBMC-humanized DKO NSG models. In CD34-humanized models, GCAR LVV generated CAR-T cells with durable B-cell depletion over >8 weeks of observation. Administration of GCAR CD20 LVV (IV or IN) was well tolerated in NHPs at all doses w/o severe CRS or neurologic toxicity. B-cell depletion kinetics post IV dosing of CD20 CARs with FD were dose dependent: minimally active doses demonstrated delayed onset of B cell depletion (from day 21 post dose) vs. B cell aplasia by day 7 at the most active doses. In contrast, a comparable GCAR LVV encoding 41BB CD20 CAR (w/o FD) by IV and IN injection elicited B cell depletion at 7 days post dose with reduced duration.\nConclusion: GCAR LVVs generated genetically modified lymphocytes resulting in durable CAR-dependent cell removal across mechanistic, murine, humanized, and NHP immune systems. The incorporation of FD may further improve cellular expansion and persistence, yielding ex vivo-like CAR-T activity profiles without lymphodepletion or cytokine support. The absence of acute and subacute safety signals, low off-target transduction, serum complement resistance, and deep B-cell depletion support the GCAR platform as a potential next-generation opportunity for clinical investigation as a novel gene modifying CAR approach.", "source_company": "EXUMA Biotech Corp", "source_org_type": "公司", "row_number": 709, "target_meta": "CD20", "MOA_meta": "其他"}, {"drug_name": "a novel CD16A-nanobody platform", "company": "Innovent Biologics (Suzhou) Co. Ltd", "org_type": "公司", "target": "CD16A", "modality": "nanobody platform", "importance_level": "中", "total_score": 74.5, "institution_score": 85, "track_score": 90, "milestone_score": 40, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "该平台基于CD16A-nanobody构建NK cell engager，克服Fc多态性限制，实现更广谱高效的NK细胞介导的抗肿瘤活性；Innovent作为国内头部biotech在热门NK engager赛道布局，但摘要禁运仅preclinical阶段信息有限。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11409", "id": "IVXM_5wBX1NQZOEH-LS6", "source_drug_name": "a novel CD16A-nanobody platform", "title": "A novel CD16A-nanobody platform overcomes Fc polymorphism limitations for potent and broad-spectrum NK cell engager therapeutics", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Innovent Biologics (Suzhou) Co. Ltd", "source_org_type": "公司", "row_number": 853, "target_meta": "CD16a", "MOA_meta": "单域抗体"}, {"drug_name": "DLL3xCD3xCD2 trispecific antibody", "company": "Probio, Inc", "org_type": "公司", "target": "DLL3", "modality": "trispecific antibody", "importance_level": "中", "total_score": 74.5, "institution_score": 65, "track_score": 90, "milestone_score": 65, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "靶点DLL3为SCLC等实体瘤验证靶点，采用DLL3xCD3xCD2三特异性TCE新机制整合CD2共刺激提升疗效和安全性；Probio作为GenScript子公司CDMO背景较强但非头部原研药企，赛道三特异性TCE+热门DLL3+实体瘤TCE优化热度高，处于IND-enabling阶段preclinical数据优于基准。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11700", "id": "sZ7M_5wBZznHJdnt_W3O", "source_drug_name": "DLL3xCD3xCD2 trispecific antibody", "title": "A novel DLL3 trispecific T cell engager antibody integrating the CD2/CD58 co-stimulatory pathway demonstrates superior antitumor efficacy and balanced safety profile", "abstract_text": "As a clinically validated therapeutic modality, T-cell engager (TCE) antibodies showed great success in hematological tumors. However, they still face a number of challenges in effectively treating solid tumors, including a lack of tumor-specific targets, insufficient T cell infiltration of some tumors, and immunosuppressive forces within the tumor microenvironment (TME) leading to T cell anergy and exhaustion. These challenges contribute to the narrow therapeutic window of TCEs in treating solid tumors and partially explain why no solid tumor-targeting TCE received regulatory approval until the DLL3-targeting tarlatamab became the first (and only to date) in 2024. To address the aforementioned challenges, a number of approaches are being explored and tested clinically, including those integrating a co-stimulatory moiety into the TCE to prevent or revert T cell exhaustion and promote sustained proliferation of the infiltrated T cells within the TME. Amongst co-stimulatory pathways, those mediated by CD28 and 4-1BB have been the most extensively explored, even though recent studies have shown that they are often associated with excessive toxicity or paradoxical immunosuppression. In contrast, the CD2-CD58 axis offers a promising alternative based on a few possible modes of actions, including promoting a balanced T cell co-stimulation at both the priming and effector stage, and stabilizing immunological synapse. Therefore, to further enhance the efficacy, persistence, and safety of conventional TCEs targeting DLL3 and other solid tumor targets, we designed a novel class of DLL3xCD3xCD2 trispecific antibodies based on an internally developed CD3 VHH antibody with cyno cross-reactivity. These trispecific TCEs were evaluated in a suite of in vitro functional assays whereby they demonstrated superior potency in tumor cell killing and sustaining T cell proliferation compared to the parental bispecific TCE (DLL3xCD3) and tarlatamab, especially at low E/T ratios, which mimics the scarcity of T cell infiltration into the TME of solid tumors. Additionally, this enhanced tumor cytotoxicity was accompanied by an increased, but balanced, cytokine profile with a reduced release of proinflammatory cytokines (TNFa, etc.), and an insignificant level of tumor antigen-independent T cell activation or cytokine release. For in vivo studies, these trispecific TCEs demonstrated a favorable IgG-like pharmacokinetics profile and greater antitumor activity than clinical benchmarks in two human PBMC-reconstituted CDX models (SHP77 and NCI-H82). In summary, the incorporation of a CD2 co-stimulatory moiety into a DLL3-targeting TCE leads to a novel, next-generation TCE with improved efficacy and safety profiles in preclinical studies. IND-enabling studies are ongoing with the potential to advance it to clinical studies in the near future.", "source_company": "Probio, Inc", "source_org_type": "公司", "row_number": 1074, "target_meta": "DLL3", "MOA_meta": "三特异性抗体"}, {"drug_name": "a couple of series of novel PARP7 inhibitors", "company": "Dong-A ST", "org_type": "公司", "target": "PARP7", "modality": "inhibitor", "importance_level": "中", "total_score": 74.5, "institution_score": 70, "track_score": 85, "milestone_score": 65, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "靶点为PARP7，通过双重机制（激活I型干扰素通路和肿瘤细胞内在细胞毒作用）发挥抗肿瘤活性，机制新颖且具免疫治疗潜力。Dong-A ST为韩国头部制药企业，赛道热度高但仍处preclinical阶段，综合潜力中等偏上。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8822", "id": "q53ECZ0B4z9FlvORyiZD", "source_drug_name": "a couple of series of novel PARP7 inhibitors", "title": "Dual mechanisms of PARP7 inhibition driving potent antitumor activity", "abstract_text": "PARP7 is a mono-ADP-ribosyltransferase that transfers a single ADP-ribose moiety to its substrates, thereby modulating protein function and contributing to the regulation of type I interferon (IFN) signaling and cellular homeostasis. In cancer models, PARP7 inhibition exhibits strong antitumor activity through a dual mechanism involving activation of the type I IFN pathway and direct tumor-intrinsic effects within cancer cells. We have developed a couple of series of novel PARP7 inhibitors, and in this study, we focused on characterizing the molecular features associated with responsiveness to PARP7 inhibitors in parallel with mechanistic studies using the clinical-stage benchmark, RBN-2397. First, in the context of antitumor immune activation, we hypothesized that interferon-stimulated gene (ISG) induction upon PARP7 inhibition is positively correlated with antitumor activity. In mouse syngeneic models, cancer cells showing strong ISG induction upon PARP7 inhibition exhibited greater antitumor responses. Combination with chemotherapeutic agents that increase cytosolic double-stranded DNA (dsDNA) further enhanced ISG induction and antitumor activity. To define ISG induction responsiveness, we screened more than 40 human cancer cell lines and categorized them as ISG responders or non-responders. Responders exhibited gene expression patterns characterized by elevated innate immune signaling and reduced genome stability. In addition to its immuno-oncological activity, PARP7 inhibition exerts an intrinsic, cell-autonomous antitumor effect, suggesting a dual mechanism of action for PARP7-targeted therapy. This intrinsic cytotoxic effect acts independently of the catalytic inhibition responsible for immune activation. While multiple mechanisms have been proposed, our data support that a PARP7 inhibitor-induced chromatin-associated trapping process represents a critical event leading to nuclear accumulation of PARP7 and subsequent DNA damage. Additionally, we confirmed that intracellular PARP7 expression is essential for PARP7 inhibitor-induced cytotoxicity. Furthermore, using the CRISPR-Cas9 system, we validated an additional key factor involved in this intrinsic cytotoxicity. Collectively, our findings demonstrate that PARP7 inhibition elicits a dual mechanism involving ISG induction and intrinsic cytotoxicity, resulting in robust antitumor activity. The key regulatory factors underlying this dual mechanism may serve as potential biomarkers for patient selection in future clinical trials and help identify individuals most likely to benefit from PARP7-targeted therapy.", "source_company": "Dong-A ST", "source_org_type": "公司", "row_number": 1083, "target_meta": "TIPARP", "MOA_meta": "抑制剂"}, {"drug_name": "NKD1-directed TCR-T cell product", "company": "Memorial Sloan Kettering Cancer Center", "org_type": "医院", "target": "NKD1", "modality": "TCR-T", "importance_level": "中", "total_score": 74.5, "institution_score": 65, "track_score": 85, "milestone_score": 75, "field_heat_score": 80, "bonus_score": 4, "brief_reason": "靶向肿瘤特异性胎儿期WNT相关抗原NKD1的TCR-T细胞疗法，针对MSS mCRC这一高未满足需求领域，机制新颖且显示出强效特异性杀伤PDO而无脱靶。机构为顶级肿瘤医院但非药企导致机构分受限，赛道为热门细胞治疗+新型共享抗原+实体瘤突破获高分，preclinical数据扎实具临床推进潜力。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9371", "id": "3J7M_5wBZznHJdnt_W3O", "source_drug_name": "NKD1-directed TCR-T cell product", "title": "Immunopeptidomic discovery of fetal WNT-associated antigen NKD1 enables HLA-A2+ restricted TCR-T therapy for MSS mCRC", "abstract_text": "T cell-engaging therapies have achieved limited success in microsatellite stable (MSS) metastatic colorectal cancer (mCRC), in part because of a paucity of truly cancer-specific targets. Systematic interrogation of the immunopeptidome, the repertoire of peptides presented by human leukocyte antigen (HLA) class I molecules, can expand the pool of druggable antigens beyond conventional surface receptors. Nonetheless, both neoantigenic driver mutations and recently described oncofetal peptides are rare or absent in most CRCs. Our recent work shows that mCRC cells adopt a highly stereotyped fetal-like phenotype, characterized by activation of a developmental WNT signaling program that is further enriched in metastasis-initiating cells and conserved across diverse patients. We hypothesized that this transcriptional reprogramming generates a cancer-specific, developmentally fixed HLA-I ligandome that can be exploited for T cell therapy. Using an integrated platform for systematic collection and multimodal profiling of matched normal colon, primary tumor, and metastases from patients undergoing CRC surgery, we established ex vivo patient-derived organoids (PDOs) that faithfully capture patient-specific CRC cell states and provide an effectively inexhaustible source of tumor cells for immunopeptidomic discovery and functional validation. In HLA-A2+ PDOs, representing the most common HLA allele, immunopeptidomic analyses identified recurrent presentation of peptides derived from fetal WNT program genes, in particular NKD1, that are prevalent across mCRC PDOs from HLA-A2+ patients and undetectable in healthy tissues. These peptides were immunogenic in vitro, eliciting robust reactivity from healthy donor T cells and supporting their suitability as therapeutic targets. Moreover, naive CD8+ T cells engineered with NKD1-specific T cell receptors (TCRs) showed strong cytokine activation and potent, antigen-dependent cytotoxicity against mCRC PDOs without detectable off-target activity, consistent with a favorable therapeutic index. Together, these data nominate NKD1 as a conserved antigen in mCRC and support the clinical advancement of an NKD1-directed TCR-T cell product as a first-in-class precision therapy for patients with MSS mCRC.", "source_company": "Memorial Sloan Kettering Cancer Center", "source_org_type": "医院", "row_number": 1107, "target_meta": "NKD1", "MOA_meta": "TCR T细胞疗法"}, {"drug_name": "PRT-001", "company": "Protai", "org_type": "公司", "target": "KAT6A", "modality": "PROTAC", "importance_level": "中", "total_score": 74.5, "institution_score": 65, "track_score": 90, "milestone_score": 60, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "PRT-001为针对KAT6A的选择性PROTAC降解剂，主要用于ER+乳腺癌，具有高选择性和有效降解活性。机构为国外新兴AI+结构蛋白质组学biotech，得分中等；PROTAC+新兴靶点KAT6A赛道热度高，处于preclinical优化阶段并展示细胞水平强效数据，综合潜力较好。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11074", "id": "Xp7ECZ0BZznHJdntvNYd", "source_drug_name": "PRT-001", "title": "Discovery of KAT6A degrader enabled by structural proteomics and AI", "abstract_text": "Lysine acetyltransferase 6 (KAT6A/B) is a MYST family member of histone acetyl transferases (HATs), with elevated activity across different cancer types. Due to its driving role in activation of hormonal signaling, KAT6 is a promising drug target specifically in estrogen receptor positive (ER+) breast cancer. Indeed, efficacy has been demonstrated in clinical trials investigating KAT6 inhibition in ER+ breast cancer. Proteolysis-targeted chimeras (PROTACs) are heterobifunctional molecules inducing the proximity between a target protein and an E3 ligase (e.g. CRBN), leading to target ubiquitination and subsequent degradation. KAT6 PROTAC can target both its enzymatic and scaffold functionalities, potentially leading to improved efficacy. In addition, selectivity towards KAT6A could increase drug tolerability and reduce adverse events.In the current work, we present a novel KAT6A-selective PROTAC, developed using the AIMS™ proteomics and AI platform. Using structural mass spectrometry (MS) data and AI modeling, we generated confident structures of the KAT6-E3-PROTAC ternary complex and identified PROTAC-dependent conformations, enabling accurate modeling of the complex for further optimization. The resulting PAI-PROTAC demonstrates efficient KAT6A degradation and growth inhibition in ER+ breast cancer cell lines, with high selectivity over KAT6B and over other KAT enzymes, as well as no degradation activity in CRBN neosubstrates. Altogether, these results illustrate how proteomics-aware-AI enables rational PROTAC design, leading to discovery of a potent and selective KAT6A degrader.", "source_company": "Protai", "source_org_type": "公司", "row_number": 1229, "target_meta": "KAT6A", "MOA_meta": "PROTAC"}, {"drug_name": "ALM-502", "company": "Almac Discovery", "org_type": "公司", "target": "ALPP/ALPPL2", "modality": "ADC", "importance_level": "中", "total_score": 74.5, "institution_score": 65, "track_score": 85, "milestone_score": 75, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "ALM-502为靶向ALPP/ALPPL2的双特异性位点ADC，采用创新双paratopic设计、小分子抗体架构、低DAR及位点特异性偶联，提升实体瘤递送和疗效。机构为Almac集团下创新biotech，非头部MNC但有ADC专业积累，得分中等偏上；ADC赛道及新型靶点（肿瘤特异性高、耐药上调）热度较高，前临床数据强（优于基准、对多瘤种有效），综合潜力较好。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5356", "id": "SJ7M_5wBZznHJdnt_W7P", "source_drug_name": "ALM-502", "title": "ALM-502: A highly effective ADC for solid tumor therapy - enhancing payload delivery through molecular design", "abstract_text": "Antibody-drug conjugates (ADCs) have transformed cancer therapy, yet their efficacy in solid tumors remains constrained by heterogeneous antigen expression, limited tumor penetration, low therapeutic index and the emergence of resistance mechanisms. ALM-502 is a highly differentiated, biparatopic ADC designed to address these challenges through innovative antibody architecture, enabling enhanced payload delivery.\nALM-502 targets ALPP/ALPPL2, developmental proteins which are over-expressed in multiple solid tumor indications but have undetectable protein expression on normal adult tissues. Additionally, ALPP/ALPPL2 are upregulated in response to standard of care treatments, providing additional therapeutic opportunities in the drug-resistant setting. The upregulation in multiple solid tumors, undetectable normal tissue expression and role in drug resistance make ALPP/ALPPL2 highly attractive targets for ADC approaches.\nALM-502 exploits multiple design features to deliver optimized performance:\n• A biparatopic binding mode increases the effective number of binding sites on the tumor cells and increases payload delivery.\n• A clinically proven, small antibody architecture is employed for enhanced tumor penetration.\n• A low payload drug-to-antibody ratio (DAR) of 2 is used to enable higher ADC dosing and plasma levels.\n• Payload attachment is via site specific conjugation to engineered sites providing a homogeneous product with excellent stability.\n• A clinically proven payload matched to indications of interest is used which delivers a strong bystander effect and is a potent inducer of immunogenic cell death.\n• The single chain antibody architecture coupled with site specific payload attachment and optimized physicochemistry facilitate high yield manufacture.\n• Improved payload delivery (for a given amount of circulating ADC) drives the therapeutic index.\nALM-502 targets two distinct epitopes and is highly selective for ALPP/ALPPL2. In in vitro assays, this biparatopic mode of binding delivers enhanced internalization into cancer cells compared to a canonical ADC. The design features of ALM-502 translate into excellent anti-tumor efficacy in ALPP/ALPPL2 positive cell-line derived xenograft (CDX) and patient-derived xenograft (PDX) models of gastric, pancreatic, ovarian and bladder cancers, which display a range of target expression. In benchmarking studies, ALM-502 consistently delivers improved efficacy over a full length DAR4 ADC on a payload equivalents basis, in both single dose and multi-dose studies.\nALM-502 has an excellent PK profile in preclinical species together with strong developability and manufacturability characteristics. These features, coupled with an ultra-low immunogenicity profile mean that ALM-502 has the potential to deliver significantly improved patient outcomes across a range of solid tumor indications with high unmet need.", "source_company": "Almac Discovery", "source_org_type": "公司", "row_number": 1231, "target_meta": "ALPP", "MOA_meta": "抗体偶联药物"}, {"drug_name": "HB0085", "company": "Shanghai Huaota Biopharmaceutical", "org_type": "公司", "target": "PTK7 & FAP", "modality": "bispecific antibody-drug conjugate", "importance_level": "中", "total_score": 74.5, "institution_score": 65, "track_score": 85, "milestone_score": 75, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "HB0085为靶向PTK7（肿瘤细胞）和FAP（CAF）的双特异性ADC，可同时作用肿瘤细胞和肿瘤微环境，显示优于单靶ADC组合的PDX模型疗效。上海华奥泰为国内中型biotech公司，Bs-ADC赛道+双靶点设计热度高，体外体内活性及PDX优效数据支撑较强preclinical里程碑。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5516", "id": "hFXM_5wBX1NQZOEH-LG5", "source_drug_name": "HB0085", "title": "A bispecific antibody-drug conjugate targeting protein tyrosine kinase 7 and fibroblast activation protein alpha simultaneously acts on tumor cells and the tumor microenvironment", "abstract_text": "Bispecific antibody-drug conjugates (Bs-ADCs) represent a significant advancement over traditional ADCs by addressing key limitations, including tumor selectivity, on-target/off-tumor toxicity, tumor heterogeneity, antigen escape, inefficient internalization, and low payload delivery efficiency. By simultaneously targeting tumor cells and cancer-associated fibroblasts (CAFs), Bs-ADCs not only enrich drug concentration at the tumor site but also disrupt the tumor's supportive stroma, thereby improving drug penetration. We have developed a Bs-ADC, HB0085, which targets tumor cells through protein tyrosine kinase 7 (PTK7) and CAFs through fibroblast activation protein (FAP), delivering a topoisomerase I inhibitor (TOP1i) payload to tumor. HB0085 has demonstrated potent antitumor activities both in vitro and in vivo. In multiple patient-derived xenograft (PDX) experiments, HB0085 achieved a tumor growth inhibition (TGI) rate greater than 70% in 42.9% (3/7) of lung cancer models and 83.3% (5/6) of pancreatic cancer models. Notably, HB0085 exhibited superior efficacy compared to combination therapy with individual monospecific ADCs targeting PTK7 and FAP in PDX models. Furthermore, when combined with the bispecific antibody HB0025 (targeting PD-L1/VEGF), the antitumor activity of HB0085 was significantly enhanced. These results position HB0085 as a promising therapeutic candidate for a range of solid tumors.", "source_company": "Shanghai Huaota Biopharmaceutical", "source_org_type": "公司", "row_number": 1252, "target_meta": "PTK7,FAP", "MOA_meta": "其他"}, {"drug_name": "CNP200137", "company": "CoBX Bio Co., Ltd.", "org_type": "公司", "target": "menin-MLL", "modality": "inhibitor", "importance_level": "中", "total_score": 74, "institution_score": 65, "track_score": 85, "milestone_score": 70, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "CNP200137为第二代menin-MLL抑制剂，针对MLL重排白血病及耐药，具有优异临床前性质和抗白血病活性。机构为韩国新兴biotech（中等偏上），热门靶点+热门机制赛道+明确第二代克服耐药亮点，但仍处临床前阶段。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11451", "id": "HVXM_5wBX1NQZOEH-LG5", "source_drug_name": "CNP200137", "title": "Discovery of CNP200137, a second-generation menin-MLL inhibitor with superior preclinical properties and anti-leukemic activity against acquired resistance", "abstract_text": "Abstract is embargoed at this time.", "source_company": "CoBX Bio Co., Ltd.\nCoBX Bio", "source_org_type": "公司", "row_number": 174, "target_meta": "menin", "MOA_meta": "抑制剂"}, {"drug_name": "MUTTA™ ADC", "company": "Aarvik Therapeutics, Inc.", "org_type": "公司", "target": "未披露", "modality": "ADC", "importance_level": "中", "total_score": 74, "institution_score": 65, "track_score": 90, "milestone_score": 65, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "MUTTA™平台构建的多表位四价ADC，针对Her2/EGFR等验证靶点展示多功能协同、内化增强及优于单靶点ADC的体外/体内疗效窗口改善，靶点未具体披露特定肿瘤抗原。Aarvik为ADC热门赛道初创公司，已完成多轮种子融资并有合作里程碑，技术创新性强但仍处早期验证阶段。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3660", "id": "pJ7M_5wBZznHJdnt_W3O", "source_drug_name": "MUTTA™ ADC", "title": "MUlti-epitope Targeting Tetravalent Antibody (MUTTA™) platform for developing NexGen ADCs with an improved therapeutic window", "abstract_text": "Antibody-drug conjugates (ADCs) are a class of targeted chemotherapeutic precision medicines that became available to oncology clinical practice in 2000. In the 25 years since, >450 ADCs have progressed into the clinic, of which only 15 ADCs have been approved by the FDA, while >130 have been discontinued or are inactive. The high failure rate (~90%) of ADCs in the clinic is often associated with factors such as low tumor antigen copy number, heterogenous expression of tumor targets in solid tumor cancers, target antigen escape, poor internalization, efficacy-limiting off-target toxicity, and developability risks. Aarvik Therapeutics has developed a novel MUlti-epitope Targeting Tetravalent Antibody (MUTTA™ ) platform to engineer NextGen ADCs with multifunctional properties to tackle difficult-to-treat solid tumor cancers. The MUTTA™ ADC platform is designed to overcome many of the limitations described above and to broaden the therapeutic window of ADCs. MUTTA™ ADCs apply an OR-gate approach and can address therapeutic limitations such as antigen escape seen with monospecific ADCs in the treatment of solid tumors. We focused initially on developing tetravalent antibody formats with optimal manufacturing properties by screening several tetravalent antibody formats using few hundred constructs and successfully identified MUTTA™ formats specifically suitable for the ADC drug development. To develop and validate the MUTTA™ platform and to test its utility to generate multifunctional therapeutic antibodies, we initially applied this technology to well-validated tumor targets such as Her2 and EGFR for which clinically proven function-blocking antibodies (e.g., trastuzumab, pertuzumab, cetuximab) are available. We successfully engineered a MUTTA™ antibody with 4 different antibody functionalities (4-in-1) and demonstrated functional synergy in blocking-ERK phosphorylation in a trastuzumab-resistant cancer cell line. We demonstrated that multi-target MUTTA™ antibodies display superior internalization over single-target antibodies. In addition, MUTTA™ ADCs exhibited superior cellular potency compared to single-target ADCs and exhibited normal IgG-like pharmacokinetic properties. We further applied the MUTTA™ platform to several solid tumors such as Breast, Colon, Lung, Ovarian, Prostate and Pancreas by first identifying complementary tumor antigens based on co-expression profiles in these solid tumor cancers and then engineering optimally-designed multi-target MUTTA™ ADCs based on this analysis. We will present data that demonstrate in vitro and in vivo validation of multi-target MUTTA™ ADCs and their improved therapeutic window compared to single-target ADCs, as well as the broad applicability of the MUTTA™ platform across several tumor antigens.", "source_company": "Aarvik Therapeutics, Inc.", "source_org_type": "公司", "row_number": 1063, "target_meta": "not available", "MOA_meta": "抗体偶联药物"}, {"drug_name": "T-cell engager", "company": "Qureator, Inc.", "org_type": "公司", "target": "未披露", "modality": "TCE", "importance_level": "中", "total_score": 73.5, "institution_score": 65, "track_score": 85, "milestone_score": 70, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "该记录聚焦临床阶段TCE在先进3D血管化肿瘤免疫微环境芯片模型中的功效与毒性（CRS）双重评估验证，靶点未披露；Qureator作为美国新兴biotech平台公司（非头部MNC）、TCE为IO热门modality且模型具IND支持价值，得分综合中等偏上。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/7359", "id": "XVXM_5wBX1NQZOEH-LK6", "source_drug_name": "T-cell engager", "title": "An advanced 3D vascularized tumor immune microenvironment on a chip for predictive efficacy and toxicity testing of IO therapeutics", "abstract_text": "Introduction: Conventional pre-clinical models for immuno-oncology (IO) therapeutics, such as animal models, suffer from irrelevant biology and ecosystems, while simple 2D/3D in vitro assays lack the complexity of the human tumor microenvironment. These gaps lead to poor prediction of clinical outcomes, including immune-related toxicities. To address this translational gap, we developed and validated an advanced, patient-relevant 3D vascularized tumor immune microenvironment (vTIME) on-a-chip model for the predictive assessment of IO drug efficacy and toxicity—a platform now proven to generate data packages supporting Investigational New Drug (IND) approval.\nMethods: Within proprietary microfluidic CurioChips, we established the vTIME model by co-culturing patient-derived organoids in hydrogel with stromal cells and endothelial cells (HUVECs). In this co-culture, endothelial cells are self-assembled into a perfusable vascular network. We subsequently introduced human monocytes, which migrated into the tumor bed and differentiated to build an immunosuppressive microenvironment. The transformation of immune microenvironment was characterized by multiple cytokine changes. We then validated the model's predictive utility using a clinical stage T-cell engager (TCE) for dual efficacy and toxicity evaluation. The tumor killing and T cell activations are measured by immunofluorescent images, immune cell profiling and secretome analysis.\nResults: The model successfully recapitulated a clinically relevant, immunosuppressive TME: monocytes differentiated into tumor-promoting macrophages, fibroblasts converted to CAF-like cells, and metastatic organoids demonstrated vascular invasion. For efficacy testing, TCE-mediated cancer-killing was observed in a dose-dependent manner; however, this efficacy was significantly diminished in the presence of immunosuppressive macrophages, demonstrating the model's ability to avoid the overestimation of efficacy seen in simpler systems. For toxicity assessment, the complete vTIME model captured the key cascade of cytokine release syndrome (CRS). TCE treatment induced a characteristic kinetic, with an initial IFNγ peak followed by a substantial IL-6 elevation. Critically, we also captured significant, CRS-linked vessel toxicity post-TCE treatment, a key initiating event of organ failure in patients.\nConclusion: These findings demonstrate that our advanced 3D vTIME-on-a-chip platform represents one of the powerful New Approach Methodologies (NAMs), which is reliable and predictive for the dual assessment of novel IO therapeutics. It is capable of capturing complex immune-mediated responses, identifying the therapeutic \"sweet spot\" balancing efficacy and toxicity, and modeling CRS-driven vascular damage not seen in conventional systems.", "source_company": "Qureator, Inc.", "source_org_type": "公司", "row_number": 36, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "CPL976H-MMAE", "company": "Celon Pharma S.A.", "org_type": "公司", "target": "PD-L1 和 AXL", "modality": "ADC", "importance_level": "中", "total_score": 73.5, "institution_score": 65, "track_score": 90, "milestone_score": 60, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "CPL976H-MMAE为双靶点（PD-L1和AXL）ADC，结合免疫检查点阻断与靶向细胞毒性，采用site-specific conjugation提升稳定性和精确递送。Celon Pharma为波兰中型biotech（非头部MNC），赛道热门（bispecific ADC+热门靶点），但仍处preclinical阶段（ex vivo PDX、PK/PD数据），综合潜力中等偏上。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5682", "id": "_lXM_5wBX1NQZOEH-LO6", "source_drug_name": "CPL976H-MMAE", "title": "Site-specific conjugation of CPL976H-MMAE enables stable and selective dual targeting of PD-L1 and AXL", "abstract_text": "Background: Combining immune checkpoint blockade with cytotoxic chemotherapy has improved survival in multiple solid tumors; however, systemic toxicity and limited response durability remain key limitations. To overcome these barriers, we developed CPL976H-MMAE, a next-generation bispecific antibody-drug conjugate (ADC) that simultaneously targets PD-L1 and AXL. This dual-target approach aims to suppress immune escape and tumor progression pathways while ensuring efficient and precise delivery of Monomethyl Auristatin E (MMAE) directly to the cancer cells.\nMaterials and Methods: CPL976H-MMAE was created with Fc-glycan remodeling and click-chemistry conjugation, resulting in an enhanced molecular stability and a standardized drug-to-antibody ratio (DAR). Target binding and stability of CPL975H-MMAE in serum were assessed by Surface Plasmon Resonance (SPR) after incubation in human, cynomolgus, mouse, and rat sera (7 days at 37°C). Pharmacokinetic and biodistribution studies were performed in MDA-MB-231 cell line xenograft models using LC-MS. Efficacy of CPL976H-MMAE was validated ex vivo in patient-derived xenografts (PDX) representing distinct PD-L1/AXL expression profiles. Potential binding to red-blood-cells (RBCs), MMAE release and its partitioning to RBCs were quantified by LC-MS in rat and cynomolgus species.\nResults: CPL976H-MMAE retained strong and stable dual-target binding across different species sera, showing highest stability in human and cynomolgus, moderate in mouse, and lowest, but still satisfactory, in rat. ADC binding and MMAE level in RBCs of mouse and cynomolgus species was negligible, even though free MMAE exhibits partial association, further indicating conjugate stability in circulation. Pharmacokinetic analyses revealed a favorable plasma clearance profile and evident, dose-dependent tumor accumulation at 0.8-6 mg/kg, with minimal off-target MMAE exposure. Ex vivo studies confirmed potent cytotoxic activity of CPL976H-MAME in PDXs expressing both high and moderate PD-L1/AXL levels.\nConclusions: CPL976H-MMAE effectively merges immune checkpoint blockade with targeted cytotoxicity, addressing both primary and acquired resistance to PD-1/PD-L1 therapies. High serum stability, sustained tumor accumulation, and limited systemic exposure presents CPL976H-MMAE as a formidable and robust bifunctional ADC. Presented data highlight CPL976H-MMAE translational potential for future therapies, especially for patients unresponsive to current immunotherapies.\nThis study was supported by The National Centre for Research and Development ( POIR.01.01.01-00-0429/19)", "source_company": "Celon Pharma S.A.", "source_org_type": "公司", "row_number": 153, "target_meta": "PDL1,AXL", "MOA_meta": "抗体偶联药物"}, {"drug_name": "itareparib", "company": "Nerviano Medical Sciences", "org_type": "公司", "target": "PARP1", "modality": "inhibitor", "importance_level": "中", "total_score": 73.5, "institution_score": 65, "track_score": 75, "milestone_score": 80, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "Itareparib是非捕获型PARP1选择性抑制剂，旨在改善与DNA损伤剂联合治疗的疗窗和安全性，已进入I/II期临床试验。Nerviano作为欧洲肿瘤专注biotech机构实力较强，非捕获PARP1i+化疗/ADC组合赛道有潜力解决未满足需求，临床阶段和非骨髓毒性亮点支撑较高评分。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3439", "id": "qVXM_5wBX1NQZOEH-LG6", "source_drug_name": "itareparib", "title": "Itareparib: A potent, selective and non-trapper PARP1 inhibitor for combination therapy with DNA damaging agents in solid tumors", "abstract_text": "BACKGROUND: The poly(ADP-ribose) polymerase-1 (PARP1) enzyme is critical to DNA Damage Response. Multiple first generation non-selective, trapping PARP1/2 inhibitors have been successful as single agent cancer treatments in homologous recombination (HR)-deficient malignancies; on the other hand, first-generation PARPi such as olaparib (a strong PARP1 trapper), or veliparib (a PARP1 trapper with medium potency), have not been successful in combination with chemotherapy due to a poor therapeutic window. Recently, second generation trapper PARP1-selective inhibitors (e.g. saruparib, M9466, SNV1521 and palacaparib) have entered clinical development, based on preclinical evidence that PARP2 inhibition is associated with anemia and dispensable for anti-tumor efficacy. However, emerging clinical data suggest that these drugs display hematological effects similar to the first generation PARPi. Indeed, all these inhibitors trap PARP1 on DNA lesions, causing hematological adverse effects that are overlapping with those caused by chemotherapy agents such as temozolomide (TMZ) and topoisomerase I inhibitors (TOP1i), thus limiting their combination potential.\nMETHODS: We used biochemical and cellular assays to evaluate itareparib potency and selectivity. Additionally, we performed cellular proliferation assays and mechanistic assays such as DNA damage markers assessment by high-content imaging and DNA combing assays, to evaluate itareparib activity in combination with DNA damaging agents (DDA). Finally, we performed in vivo experiments in tumor bearing mice and tumor free rats to assess the combination effects of itareparib plus TMZ on tumor growth inhibition and on the bone marrow.\nRESULTS: Itareparib is a non-trapper PARPi and showed synergistic activity in combination with TMZ and TOP1i or Antibody Drug Conjugates (ADCs) with TOP1i payloads on DNA damage markers and in proliferation assays in vitro. The combination efficacy with temozolomide was confirmed in vivo in a small cell lung cancer xenografts model. Additionally, the comparative data with trapper-PARPi suggests that the combination efficacy with TMZ and TOP1i is not dependent on the trapping potency. Importantly, itareparib combination with DDA had lower impact on bone marrow precursors both in vitro and in vivo compared to PARP1-trapping inhibitors. Consistently with literature data, in vitro studies identify SLFN11 expression as a sensitivity biomarker to the combination of itareparib with chemotherapy.\nCONCLUSIONS: Itareparib features are designed to expand the application of PARP1i through combination with chemotherapy, ADCs and radionuclides addressing the unmet need of patients with both HR-deficient and HR-proficient tumors. Itareparib is currently in Phase I/II clinical trials in combination with DNA-damaging agents in brain (high grade gliomas), lung and ovarian cancer.", "source_company": "Nerviano Medical Sciences", "source_org_type": "公司", "row_number": 191, "target_meta": "PARP1", "MOA_meta": "抑制剂"}, {"drug_name": "AL-0433", "company": "Eilean Therapeutics", "org_type": "公司", "target": "CDK4", "modality": "inhibitor", "importance_level": "中", "total_score": 73.5, "institution_score": 75, "track_score": 80, "milestone_score": 65, "field_heat_score": 75, "bonus_score": 4, "brief_reason": "AL-0433为新型高选择性脑渗透CDK4抑制剂，针对CDK4而非CDK6以降低血液毒性并提升疗效窗口，适用于乳腺癌、卵巢癌及胶质母细胞瘤等。机构为由知名VC Orbimed和Torrey Pines支持的国外biotech公司，赛道为热门细胞周期靶向+脑渗透小分子抑制剂但仍处preclinical，AI辅助设计及良好体内外数据为其亮点。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6422", "id": "vFXM_5wBX1NQZOEH-LG6", "source_drug_name": "AL-0433", "title": "Discovery of a novel, selective brain penetrant CDK4 inhibitor for targeted cancer therapy", "abstract_text": "In breast and other malignancies, CDK4 overactivation commonly occurs as a result of sustained endocrine and mitogenic inputs, dysregulated cyclin D1 expression, or the genetic loss or functional impairment of INK4 family inhibitors, or loss of endogenous inhibitors such as p16. Approved CDK4/6 inhibitors (palbociclib, ribociclib, and abemaciclib) are associated with hematologic toxicity, including neutropenia, linked to CDK6 rather than CDK4 inhibition. Since these drugs block CDK6, drug dosing is restricted by bone marrow suppression rather than anti-tumor efficacy. HR+ breast cancer cells are more dependent on CDK4 than CDK6 for proliferation, whereas normal hematopoiesis relies predominantly on CDK6. Loss of CDK4 alone does not impair blood cell development in mice, while CDK6 and its partner cyclin D3 play a key role in stem cell activation, erythroid and myeloid differentiation, and neutrophil maintenance. This divergence establishes a therapeutic window: Selective blockade of CDK4 could suppress tumor growth while sparing bone marrow function. Clinical benefits in patients with brain metastases have been documented. However, dose-limiting toxicity may prevent the gain in overall outcome. CDK4-selective inhibition represents a strategic evolution in targeting cell-cycle dysregulation. By sparing CDK6, agents aim to overcome the main toxicity barrier of dual CDK4/6 inhibitors, enabling more potent and sustained CDK4 blockade. Here, we describe AL-0433, a novel, selective brain penetrant CDK4 inhibitor with excellent in vitro and in vivo activity.\nMethods: AL-0433 was developed using resistance-aware, structure-based design, via AI-enabled virtual screening and medicinal chemistry at Expert Systems. Potency was evaluated against CDK1, 2, 4, 6, 9, and GSK3b in biochemical assays, and cytotoxicity was assessed in breast, ovarian, and glioblastoma cell lines. Pharmacokinetic (PK) properties were characterized in murines and dogs. Anti-tumor efficacy was tested in MCF-7 xenograft models as a single agent and in combination with other anti-tumor agents.\nResults: AL-0433 exhibited low-nanomolar CDK4 inhibition (2.7 nM) with 30-fold selectivity over CDK6, and 1000-fold selectivity over CDK1, CDK2, and CDK9. AL-0433 showed potent cytotoxicity in breast, ovarian, and glioblastoma cells (20-950 nM). Mechanism of action studies in MCF-7 cells demonstrated inhibition of pRB phosphorylation. AL-0433 demonstrated excellent oral bioavailability with high blood-brain barrier (BBB) permeability, making it particularly advantageous for treating both primary and metastatic tumors, as well as brain tumors such as glioblastoma.\nConclusion: AL-0433 is a promising, AI-designed, selective CDK4 inhibitor with broad activity across breast, ovarian, and glioblastoma cell lines. Its favorable PK profile, preclinical efficacy, and rational design strategy support further clinical development", "source_company": "Eilean Therapeutics", "source_org_type": "公司", "row_number": 198, "target_meta": "CDK4", "MOA_meta": "抑制剂"}, {"drug_name": "EV-siRNA #41", "company": "Exollence Biotechnology Co. Ltd.", "org_type": "公司", "target": "KRAS G12D", "modality": "siRNA", "importance_level": "中", "total_score": 73.5, "institution_score": 55, "track_score": 90, "milestone_score": 80, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "药物针对KRAS G12D突变胰腺癌，利用shock wave-engineered EV递送化学修饰siRNA，实现allele-specific沉默和显著肿瘤消退，微剂量下媲美或优于MRTX1133，显示first-in-class潜力。机构为韩国新兴biotech，得政府资助但非头部，赛道为热门KRAS+siRNA+exosome递送，preclinical数据强且ready for IND。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4354", "id": "-FXM_5wBX1NQZOEH-LG6", "source_drug_name": "EV-siRNA #41", "title": "EV-based delivery of chemically modified siRNA achieves MRTX1133-comparable efficacy in KRAS G12D-mutant pancreatic cancer", "abstract_text": "Background: KRAS G12D-mutant pancreatic ductal adenocarcinoma (PDAC) remains largely incurable, with no clinically validated targeted therapies. RNA interference can selectively suppress mutant KRAS, yet current delivery technologies fail to achieve sustained, safe in vivo activity. We developed a shock wave-engineered extracellular vesicle (EV) platform (SWEET™) that enables efficient, stable encapsulation of KRAS G12D-targeting siRNA and overcomes key limitations of lipid nanoparticles (LNPs) and small-molecule inhibitors.\nMethods: We designed and screened a 105-member panel of chemically modified siRNAs engineered for high stability and reduced innate immune activation to identify potent and allele-specific KRAS G12D silencers. Optimized shock-wave engineering achieved >90% encapsulation and >85% nuclease resistance. Lead candidates were evaluated across PDAC cell lines, patient-derived organoids (PDOs), xenografts, biodistribution studies, toxicity models, and GMP-aligned scale-up workflows.\nResults: Five siRNAs exhibited single-digit nanomolar potency (IC50 < 10 nM). The lead, EV-siRNA #41, produced robust KRAS G12D knockdown and suppression of ERK/AKT signaling. In vivo, EV-siRNA #41 achieved markedly superior tumor accumulation relative to LNPs and induced significant tumor regression. Notably, a microdose of 25 μg EV-siRNA #41 produced antitumor efficacy comparable to or exceeding MRTX1133 at 30-60 mg/kg. PDO assays confirmed selective killing of KRAS G12D-mutant tumors with no effect on wild-type controls. Repeated-dose GLP toxicity studies established a high NOAEL without liver enzyme elevation or weight loss. GMP-aligned optimization increased EV yield from 1% to 7.5% with >80% loading efficiency.\nConclusions: Shock wave-engineered EV delivery overcomes the major barriers of RNA therapeutics in PDAC. EV-siRNA #41 demonstrates potent, selective, and durable antitumor activity at microdose levels and outperforms both LNPs and a leading KRAS G12D inhibitor. These data position EV-siRNA #41 as a first-in-class, mutation-specific RNA therapeutic ready for IND-enabling development.\nAcknowledgments: This work was supported by the Korea Drug Development Fund (KDDF, Grant No. RS-2023-00282594), the Technology Development Program of the Ministry of Science and ICT (MSS, Grant No. RS-2023-00280797), and the Ultra-Gap Startup 1000+ Project for the promotion of ultra-gap startups, funded by the Ministry of SMEs and Startups of Korea in 2025 (Grant No. 20266766).", "source_company": "Exollence Biotechnology Co. Ltd.", "source_org_type": "公司", "row_number": 206, "target_meta": "KRAS G12D", "MOA_meta": "其他"}, {"drug_name": "cLRRC15-IFNα", "company": "Bonum Therapeutics", "org_type": "公司", "target": "LRRC15", "modality": "other", "importance_level": "中", "total_score": 73.5, "institution_score": 75, "track_score": 80, "milestone_score": 60, "field_heat_score": 75, "bonus_score": 5, "brief_reason": "药物通过条件激活机制靶向LRRC15+癌相关成纤维细胞递送IFNα，实现CAF重编程和免疫激活，机制新颖。Bonum为国外有Roche收购前身经验的创新biotech，赛道为肿瘤微环境热门靶向调节但preclinical阶段，总分中等偏高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4565", "id": "QVXM_5wBX1NQZOEH-LK6", "source_drug_name": "cLRRC15-IFNα", "title": "Safety and activity of cLRRC15-IFNa, a conditionally active biologic targeting IFNa specifically to LRRC15+ CAFs", "abstract_text": "While cancer-associated fibroblasts (CAFs) have emerged as a key cell type capable of influencing malignant cell growth, this axis of cancer biology has not yet been exploited for therapeutic benefit. CAFs enable tumor growth through multiple mechanisms including deposition of extracellular matrix, production of soluble factors, and inhibition of the immune response. Recent advancements have revealed how distinct CAF populations correlate with patient prognosis and response to therapies across many solid tumor types. Amongst these CAF subsets, LRRC15 expression has been shown to identify a myofibroblast population with a central functional role in supporting tumor cell growth and inhibiting anti-tumor immune responses. Approaches to reprogram or reduce this LRRC15+ population of CAFs may provide therapeutic benefit in multiple solid tumor indications.\nIFN-α signaling directly on tumor-supporting CAFs drives reprogramming, countering the TGF-β signal on which the phenotype depends. IFN-α also effectively promotes both innate and adaptive immune responses, including dendritic cell maturation, repolarization of suppressive myeloid cells, and CD8+ T cell activation. However, the use of systemic IFN-α therapy has been limited by significant dose-limiting toxicities.\nWe have generated a conditionally active cLRRC15-IFNα therapeutic that targets IFN-α activity to LRRC15+ cells while remaining largely inactive on other cells. Our approach uses a novel dual-binding antibody (DBA) mechanism that takes advantage of the ability of an antibody to bind specifically and competitively to two distinct antigens. With this technology, IFN-α is bound and inactive in circulation and only becomes active when the therapeutic binds to LRRC15.\nOnce localized to the surface of an LRRC15+ CAF, cLRRC15-IFNα exerts anti-tumor activity both by direct cis-signaling of IFN-α on CAFs and by trans-signaling to adjacent immune cells. In vitro, reporter cell and receptor binding assays demonstrate that cLRRC15-IFNα has >100-fold preferential IFN-α activity in the presence of LRRC15. In primary cells, cLRRC15-IFNα preferentially induces IFN-α signaling in LRRC15-expressing activated human fibroblasts. cLRRC15-IFNα inhibits tumor growth in mouse syngeneic tumor models, avoids clinical signs of IFN-α-mediated toxicity, and demonstrates robust combinatorial activity with anti-PD-1. In the TME, cLRRC15-IFNα drives the activation of CD8+ T cells. Collectively, these results demonstrate the potential of the DBA platform and support the clinical development of cLRRC15-IFNα.", "source_company": "Bonum Therapeutics", "source_org_type": "公司", "row_number": 213, "target_meta": "LRRC15", "MOA_meta": "其他"}, {"drug_name": "HZ-V055", "company": "HealZen Therapeutics Co., Ltd.", "org_type": "公司", "target": "pan-Ras", "modality": "molecular glue inhibitor", "importance_level": "中", "total_score": 73.5, "institution_score": 75, "track_score": 95, "milestone_score": 40, "field_heat_score": 90, "bonus_score": 5, "brief_reason": "HZ-V055为口服高活性pan-Ras分子胶抑制剂，直接靶向Ras突变癌模型显示强劲疗效，靶点为pan-Ras属于RAS领域最热门赛道之一。机构为国内临床阶段biotech，有J&J出许可亮点但非头部，摘要仍保密仅preclinical水平。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11452", "id": "fFXM_5wBX1NQZOEH-LO6", "source_drug_name": "HZ-V055", "title": "HZ-V055, an oral, highly potent pan-Ras molecular glue inhibitor demonstrated robust potency in RasMut cancer models", "abstract_text": "Abstract is embargoed at this time.", "source_company": "HealZen Therapeutics Co., Ltd.", "source_org_type": "公司", "row_number": 242, "target_meta": "Ras", "MOA_meta": "抑制剂"}, {"drug_name": "proprietary E3 ligase binder", "company": "FIMECS, Inc.", "org_type": "公司", "target": "未披露", "modality": "other", "importance_level": "中", "total_score": 73.5, "institution_score": 65, "track_score": 90, "milestone_score": 60, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "该平台聚焦于靶向蛋白降解领域中关键的E3连接酶配体发现，采用表型筛选策略识别新型低骨髓表达E3酶，有望降低骨髓毒性并实现口服生物利用度。FIMECS作为专注TPD的日本biotech公司虽非头部MNC但技术平台有一定创新性，赛道热度高但仍处平台技术/preclinical阶段故总分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6463", "id": "dlXM_5wBX1NQZOEH-LG5", "source_drug_name": "proprietary E3 ligase binder", "title": "Expanding the landscape of targeted protein degradation: E3-agnostic discovery and proprietary ligand identification", "abstract_text": "Targeted protein degradation (TPD) is a promising therapeutic modality, but its broader application is constrained by the lack of established strategies to select optimal E3 ligases for specific targets. Although many E3 ligases exist, only a few have been leveraged in degraders currently undergoing clinical trials, leaving much of the ligase space unexplored. To address this challenge, a proprietary TPD discovery platform enables rational E3 ligase selection in a high-throughput manner through a workflow that integrates fragment-based diversity-oriented synthesis (DOS) with phenotypic screening in relevant cell models. This workflow, supported by in-house capabilities for high-throughput compound synthesis, generates diverse chemical scaffolds and identifies degrader candidates with desired activity profiles. Phenotypic screening ensures functional relevance and facilitates the discovery of compounds that engage E3 ligases not previously applied in TPD, thereby expanding the scope of ligase-targeted degradation strategies. Lead compounds are refined through optimization and E3 ligase deconvolution to confirm ligase engagement and improve molecular properties such as potency, selectivity, and drug-likeness. Once novel E3 ligase binders are identified through this process, they open up new application opportunities. One path is to incorporate the binder into our internal E3 ligase toolbox and apply it to other targets as part of bifunctional degrader design. Another is to evaluate whether the binder can function as a molecular glue, enabling degradation through neo-substrate recruitment. Importantly, our phenotypic screening approach has led to the identification of proprietary E3 ligases with low expression in bone marrow and hematopoietic tissues. Degraders based on these E3 ligase binders demonstrate the potential to avoid bone marrow toxicity—a major concern for cancer targets—while maintaining robust activity. This strategy not only enables the development of orally bioavailable molecules with improved pharmacokinetics and broad target applicability, but also provides a path to safer TPD therapeutics. By expanding the usable E3 ligase toolbox, this proprietary platform unlocks new degrader modalities and supports the development of therapeutics with improved physicochemical properties, including orally bioavailable candidates. This presentation will highlight case studies demonstrating how this platform contributes to the advancement of novel E3 ligase-based TPD, offering a scalable, versatile, and forward-looking solution to a key bottleneck in the field.", "source_company": "FIMECS, Inc.", "source_org_type": "公司", "row_number": 389, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "Invivo CAR-T", "company": "GenoBioTX LLC", "org_type": "公司", "target": "CD19", "modality": "CAR", "importance_level": "中", "total_score": 73.5, "institution_score": 65, "track_score": 90, "milestone_score": 55, "field_heat_score": 80, "bonus_score": 0, "brief_reason": "Invivo CAR-T针对CD19，通过病毒载体或tLNP递送CAR基因/mRNA，实现体内CAR-T生成并高效清除B细胞；GenoBioTX作为专注基因工程小鼠模型和preclinical CRO的中小型biotech机构得分中等，赛道为热门的in vivo CAR领域但本项为工具模型验证而非药物开发里程碑，综合热度较高，总分处于中档。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6753", "id": "8VXM_5wBX1NQZOEH-LG6", "source_drug_name": "Invivo CAR-T", "title": "HSC-humanized mouse model: Invivo CAR-T mediated B-cell depletion and application in targeted drug screening", "abstract_text": "Background: In the research of targeted therapy for B-cell related malignant tumors and autoimmune diseases, traditional animal models have limitations such as significant species differences and inadequate mimicry of human immune function, which hinder the efficiency of drug development. Hematopoietic Stem Cell (HSC)-humanized mice can reconstitute a functional human immune system, providing an ideal in vivo research platform to address these issues. Their application value in the evaluation of in vivo CAR-T (Invivo CAR-T) therapy and screening of innovative drugs urgently needs to be verified.\nMethods: A standardized protocol was used to construct the HSC-humanized mouse model: Severe immunodeficient NMG mice were preconditioned with sublethal dose irradiation (1.2 Gy) to disrupt the endogenous hematopoietic system and create space for human HSC engraftment. Subsequently, 1.5×10^5 sorted and purified human umbilical cord blood-derived CD34+ HSCs per mouse were transplanted via tail vein injection. After stable model reconstitution (peripheral blood hCD45+ cell ratio ≥25%), the CD19-targeted Invivo CAR-T system was used for intervention. CAR gene/mRNA was delivered via viral vectors (e.g., lentivirus, adeno-associated virus) or targeted lipid nanoparticles (tLNP). Following a single administration, the B-cell depletion efficiency in peripheral blood and spleen, as well as the CAR transfection positive rates in CD4+ T cells and CD8+ T cells, were detected simultaneously.\nResults: After transplantation, CD34+ HSCs successfully engrafted in the bone marrow of HSC-humanized mice and achieved multi-lineage differentiation, forming a stable population of human immune cells. The immune reconstitution exhibited a time-dependent characteristic: T cells accounted for 40%-50% at 14-20 weeks, B cells were the dominant population in the early stage, accompanied by low-proportion reconstitution of myeloid cells such as NK cells (average proportion ~2%) and monocytes. Human immune checkpoint molecules were expressed on the surface of immune cells. After Invivo CAR-T intervention, autologous B cells in the peripheral blood and spleen of mice were significantly depleted with a near-complete clearance efficiency, and positive CAR expression was detected in both CD4+ T cells and CD8+ T cells. Further analysis showed that B-cell reconstitution was dominated by naive B cells after depletion, suggesting functional resetting of the immune system. By synchronously monitoring CAR transfection efficiency and target cell clearance effect, it provides crucial technical support for the efficacy screening, dosage optimization, and safety evaluation of innovative drugs targeting B cells.", "source_company": "GenoBioTX LLC", "source_org_type": "公司", "row_number": 478, "target_meta": "CD19", "MOA_meta": "其他"}, {"drug_name": "antifolate ADC", "company": "Byondis B.V.", "org_type": "公司", "target": "未披露", "modality": "ADC", "importance_level": "中", "total_score": 73.5, "institution_score": 65, "track_score": 85, "milestone_score": 70, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "药物为新型抗叶酸ADC，靶点未披露，真靶点为DHFR抑制但ADC整体以抗叶酸payload为创新点。Byondis为专注ADC的欧洲中小型biotech，IND-enabling阶段显示较强preclinical疗效和制造进展，抗叶酸新MoA在ADC耐药背景下有差异化潜力。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4444", "id": "WVXM_5wBX1NQZOEH-LK6", "source_drug_name": "antifolate ADC", "title": "Antifolate ADCs, a novel linker-drug platform for targeted therapy with a clear differentiating mechanism of action", "abstract_text": "Background: Clinical resistance to dominant ADC payloads - topoisomerase-I inhibitors and tubulin inhibitors - is increasing, underscoring the need for novel payloads with a differentiated mechanism of action (MoA). Methotrexate (MTX), a pioneering antifolate, revolutionized oncology and autoimmune disease treatment but suffers from poor tumor selectivity and systemic toxicity. Despite its clinical validation, MTX and related antifolates have not been successfully adapted into targeted therapies. Byondis revisited the class of antifolates and optimized these to a proprietary novel linker-drug platform currently in IND-enabling studies.\nResults: Byondis developed a first-in-class antifolate linker-drug platform, featuring optimized payloads with a low- to sub-nanomolar potency and suitable for linker coupling. The resulting optimized payload demonstrates potent inhibition of dihydrofolate reductase (DHFR), in vitro cytotoxicity in a broad panel of cell lines, minimal affinity for resistance-associated transporters (BCRP, PGP), and favorable physicochemical properties allowing for the ongoing GMP-scale up of the linker-drug (LD) and good ADC manufacturability. The selected optimized linker contains a glucuronide moiety with the aim to improve the therapeutic index. The PhysChem properties of the LD demonstrates / ensures minimal impact on ADC hydrophobicity after conjugation and perfectly allows its use in a future dual payload approach. The Byondis’ lead antifolate ADC is based on the novel antifolate LD platform. This antifolate ADC is based on a yet undisclosed tumor antigen targeting antibody. It shows strong in vitro cytotoxicity across a broad tumor cell-line panel and in a deruxtecan insensitive cell-line. Robust in vivo efficacy in NSCLC and HNSCC patient-derived xenograft models is demonstrated, with no significant toxicity at doses resulting in tumor regressions. The antifolate ADC delivers optimal pharmacokinetics and anti-tumor activity. GMP manufacturing of the linker-drug is underway.\nConclusions: The antifolate platform reintroduces a clinically validated MoA into the ADC landscape with enhanced selectivity, potency, and manufacturability. Its orthogonal MoA offers potential across different tumor types including an advantage in overcoming resistance to existing ADCs and supports sequential ADC therapy. With broad applicability across tumor types, antifolate-based ADCs are poised to address unmet clinical needs and are ready for clinical translation.", "source_company": "Byondis B.V.", "source_org_type": "公司", "row_number": 543, "target_meta": "not available", "MOA_meta": "抗体偶联药物"}, {"drug_name": "dual-payload antibody-drug conjugates", "company": "OBI Pharma, Inc", "org_type": "公司", "target": "未披露", "modality": "ADC", "importance_level": "中", "total_score": 73.5, "institution_score": 65, "track_score": 90, "milestone_score": 60, "field_heat_score": 85, "bonus_score": 3, "brief_reason": "双负载ADC技术平台研究，聚焦细胞内释放机制优化，未披露具体靶点；OBI Pharma作为台湾临床阶段ADC专注biotech有一定实力，双负载ADC属ADC热门前沿方向但本条为方法学preclinical研究。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6474", "id": "alXM_5wBX1NQZOEH-LK6", "source_drug_name": "dual-payload antibody-drug conjugates", "title": "Cell based payload release highlights design, site, and cell dependent ratio shifts in dual payload ADCs", "abstract_text": "Dual-payload antibody-drug conjugates (ADCs) are designed to deliver two cytotoxic payloads in a defined ratio, yet whether this designed composition is maintained upon cellular processing is poorly understood. Conventional enzymatic payload release assays confirm linker cleavability but fail to reflect the biological complexity governing intracellular release. To address this, we established a quantitative cell-based liquid chromatography payload-release assay to monitor intracellular drug liberation after ADC treatment across multiple tumor cell lines. Using this platform, we examined how linker design, conjugation site, drug-to-antibody ratio (DAR), and steric environment affect payload release of mono- and dual-payload ADCs. While all constructs exhibited analytically confirmed enzymatic cleavability, the intracellular release profiles frequently diverged from the designed A:B payload ratios. Notably, the extent and direction of these ratio shifts were cell-type dependent, even for the same ADC construct, indicating that differences in protease abundance, endolysosomal trafficking, and microenvironmental pH strongly modulate payload liberation. Furthermore, conjugation site and DAR configuration introduced steric shielding effects that altered linker accessibility and release kinetics, resulting in distinct and less than optimal intracellular payload ratios despite identical chemical designs. Importantly, cell-based release results correlated closely with cytotoxicity outcomes in animal models, underscoring their functional relevance. Together, these findings reveal that the custom-designed dual-payload ratio does not necessarily reflect the effective intracellular ratio, and that cellular context, linker architecture, and conjugation geometry collectively determine the eventual payload balance. This framework provides a mechanistically informative tool for rational optimization of dual-payload ADC design, enabling more predictive control of intracellular pharmacology.", "source_company": "OBI Pharma, Inc", "source_org_type": "公司", "row_number": 554, "target_meta": "not available", "MOA_meta": "抗体偶联药物"}, {"drug_name": "PSMA/STEAP1 BsADC", "company": "Hongcheng Biopharma", "org_type": "公司", "target": "PSMA 和 STEAP1", "modality": "bispecific ADC", "importance_level": "中", "total_score": 73.5, "institution_score": 55, "track_score": 90, "milestone_score": 75, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "该BsADC双靶向PSMA和STEAP1并搭载双不同机制payload（tubulin抑制剂和TOP1抑制剂），解决mCRPC中抗原异质性和逃逸问题，preclinical数据强劲包括异质模型中持久肿瘤消退。机构为国内中小型biotech非头部，得分一般；赛道为热门双特异性ADC+双payload创新，热度高；综合潜力较好但未临床。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4480", "id": "a1XM_5wBX1NQZOEH-LO6", "source_drug_name": "PSMA/STEAP1 BsADC", "title": "Bispecific antibody with dual-payload ADC for metastatic castration-resistant prostate cancer", "abstract_text": "Treatment of metastatic castration-resistant prostate cancer (mCRPC) remains a significant clinical challenge. While monospecific ADCs have shown promise, target heterogeneity often leads to treatment resistance and relapse. To address this, we developed a bispecific ADC (BsADC) targeting both Prostate-Specific Membrane Antigen (PSMA) and Six-Transmembrane Epithelial Antigen of the Prostate 1 (STEAP1). The BsADC is armed with two distinct payloads with different mechanism of action: designed to enhance antitumor efficacy through dual antigen targeting and synergistic payload mechanisms. A humanized bispecific antibody against PSMA and STEAP1 was generated. The antibody was site-specifically conjugated with tubulin inhibitor and a topoisomerase 1 inhibitor. The PSMA/STEAP1 BsADC demonstrated optimal affinity, simultaneous binding to both targets, with no observable cross-reactivity to unrelated antigens. Unlike monospecific ADC, the BsADC was efficacious against cell lines expressing either or both antigens. The combination of MMAE and TOP1i payloads induced synergistic cell killing. In vivo, the dual-targeted, dual-payload BsADC achieved robust and durable tumor regressions in both homogeneous (PSMA+STEAP1+) and critically, in heterogeneous xenograft models. We have successfully developed a novel BsADC that co-targets PSMA and STEAP1 and delivers two mechanistically distinct warheads. This approach mitigates the issue of antigen escape and leverages synergistic payload activity, resulting in superior efficacy against heterogeneous prostate tumors. Our compelling preclinical data warrant further clinical development, and this BsADC represents a promising therapeutic candidate for patients with mCRPC, including those resistant to current ADC therapies.", "source_company": "Hongcheng Biopharma", "source_org_type": "公司", "row_number": 721, "target_meta": "PSMA,STEAP1", "MOA_meta": "抗体偶联药物"}, {"drug_name": "novel series of SMARCA2-selective small molecule inhibitors", "company": "Onco3R Therapeutics", "org_type": "公司", "target": "SMARCA2", "modality": "inhibitor", "importance_level": "中", "total_score": 73.5, "institution_score": 65, "track_score": 85, "milestone_score": 70, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "靶向SMARCA2的选择性小分子抑制剂，利用SMARCA4缺失肿瘤的合成致死机制，展现best-in-class潜力和体内抗瘤活性。机构为欧洲新兴临床阶段biotech（有在研项目进入I期），赛道热门（选择性SMARCA2抑制在SMARCA4突变癌中具高潜力），目前处临床前lead阶段但数据扎实。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8664", "id": "jlXM_5wBX1NQZOEH-LO6", "source_drug_name": "novel series of SMARCA2-selective small molecule inhibitors", "title": "Discovery of novel SMARCA2 small molecule inhibitors with best-in-class potency and selectivity for the treatment of SMARCA4-mutant cancers", "abstract_text": "Patients with homozygous loss-of-function (LOF) mutations in SMARCA4 constitute a molecularly distinct subgroup of non-small-cell lung cancer (NSCLC), encompassing approximately 5% of all patients. This subset is defined by its mutual exclusivity with other oncogenic drivers and demonstrates resistance to standard treatments, including radiotherapy, chemotherapy, and PD-L1 inhibitors. Notably, SMARCA4 LOF can co-occur with KRAS-G12C mutations, leading to resistance against KRAS-targeted therapies.\nMechanistically, the loss of SMARCA4 function creates a synthetic lethal dependency on SMARCA2, a vulnerability that has been validated through both genetic and pharmacological approaches. However, the development of selective SMARCA2 inhibitors remains challenging due to the high sequence homology between SMARCA2 and SMARCA4—yet achieving selectivity is critical for clinical success. Previous clinical trials with a dual SMARCA4/2 inhibitor were discontinued due to safety concerns, highlighting the urgent need for potent and selective SMARCA2 inhibitors. Addressing this therapeutic gap could unlock the full potential of targeting SMARCA2 in SMARCA4-deficient cancers.\nAt Onco3R Therapeutics, our patient-centric strategy—combining deep translational science with rational, structure-based and AI-augmented drug design—has led to the discovery of a novel series of SMARCA2-selective small molecule inhibitors with a best-in-class potency and selectivity profile. Lead compounds exhibited single digit to sub-nanomolar activity and over 30-fold selectivity for SMARCA2 versus SMARCA4, as demonstrated in a KRT80 qRT-PCR assay using SMARCA2/4 isogenic knockout cell lines.\nNotably, these lead compounds combined potent anti-proliferative effects in SMARCA4-deficient cells with favourable in vitro ADME characteristics, a supportive safety profile and pharmacokinetic properties suitable for in vivo evaluation. Following oral administration, the compounds achieved sustained target engagement and elicited pronounced anti-tumor activity in a SMARCA4-deficient RERF-LC-A1 CDX mouse model without evidence of SMARCA4-related body weight loss.\nThese unique SMARCA2-selective lead compounds are currently further profiled as potential clinical candidate with the ultimate goal of delivering transformative efficacy and enhanced safety for patients with SMARCA4-deficient cancers.", "source_company": "Onco3R Therapeutics", "source_org_type": "公司", "row_number": 745, "target_meta": "SMARCA2", "MOA_meta": "抑制剂"}, {"drug_name": "orally bioavailable peptide macrocycles", "company": "Circle Pharma, Inc.", "org_type": "公司", "target": "cyclin family proteins RxL-binding site", "modality": "macrocyclic peptide", "importance_level": "中", "total_score": 73.5, "institution_score": 75, "track_score": 85, "milestone_score": 55, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "药物为口服生物可利用的肽大环化合物，选择性抑制cyclin家族蛋白的RxL结合位点，破坏细胞周期相关蛋白-蛋白相互作用，具有针对E2F高表达肿瘤的新机制潜力。Circle Pharma为专注大环平台的临床阶段biotech公司，赛道热门（口服大环肽+细胞周期调控），但该条摘要无具体实验数据，仅为preclinical描述，故里程碑分中等，总分处于中偏高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3622", "id": "nVXM_5wBX1NQZOEH-LO6", "source_drug_name": "orally bioavailable peptide macrocycles", "title": "Orally bioavailable peptide macrocycles disrupting intracellular protein-protein pnteractions: Selective pnhibitors of the RxL-binding site of cyclin family proteins", "abstract_text": "There is no abstract associated with this presentation.", "source_company": "Circle Pharma, Inc.", "source_org_type": "公司", "row_number": 754, "target_meta": "cyclin", "MOA_meta": "其他"}, {"drug_name": "engineered IL-18 variants", "company": "Suzhou Forlong Biotechnology Co., Ltd", "org_type": "公司", "target": "IL-18R1", "modality": "other", "importance_level": "中", "total_score": 73.5, "institution_score": 65, "track_score": 85, "milestone_score": 70, "field_heat_score": 80, "bonus_score": 4, "brief_reason": "药物为工程化IL-18变体，靶向IL-18R1并完全逃逸IL-18BP抑制，实现可调IL-18活性；Forlong为国内临床阶段biotech，专注细胞因子疗法，赛道热门（工程化细胞因子+免疫治疗），有小鼠模型中98%抑瘤的融合蛋白初步POC，综合潜力中等偏上。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9592", "id": "-1XM_5wBX1NQZOEH-LO6", "source_drug_name": "engineered IL-18 variants", "title": "A tunable interleukin-18 (IL-18) platform engineered for complete escape from the decoy receptor IL-18 binding protein (IL-18BP)", "abstract_text": "Background: IL-18 is a potent immune cytokine that promotes CD8⁺ T-cell- and NK-cell-mediated antitumor responses. Its therapeutic potential is limited by rapid neutralization by IL-18BP, poor stability, short half-life, and systemic toxicity. Multiple efforts have attempted to generate IL-18 variants that escape IL-18BP neutralization, but current variants either retain residual IL-18BP binding or require extensive mutations. Our goal was to produce IL-18 variants fully resistant to IL-18BP with minimal mutations while maintaining controlled IL-18 activity via engaging the IL-18 receptor (IL-18R1).\nMethods: Using structural modeling with our AI-driven Intelligent Biomolecular Discovery Platform, we identified amino acids critical for IL-18BP and IL-18R1 interactions. A combinatorial IL-18 library was constructed by site-directed mutagenesis and displayed on yeast. Variants that lost IL-18BP binding but retained IL-18R1 interaction were enriched by FACS. DNA coding sequences of positive clones were Sanger sequenced, subcloned into mammalian expression vector. And recombinant proteins were purified. IL-18R1-specific binding and IL-18BP escape were confirmed by ELISA, and binding KDs were determined by bio-layer interferometry. Functional activity was assessed by IFN-γ production from human PBMCs in the presence of 5 µg/mL IL-18BP.\nResults: We initially identified a positive clone named E8 which showed reducing binding affinity to IL-18BP. We further obtained more than 200 clones which completely lost binding to IL-18BP from a secondary library based on the sequence of E8. Multiple sequence alignment revealed that clones with few amino acid mutations could fully abolish IL-18BP binding while retaining minimal IL-18R1 interaction. In addition, specific amino acid positions were identified whose single or combined mutation restored IL-18R1 affinity. Combinatorial mutations of specificity-related and affinity-related amino acids yielded a panel of over 100 IL-18 variants with IL-18R1 binding KDs ranging from 10⁻⁹ to 10⁻⁷ M and complete loss of IL-18BP binding. Representative variants activated human PBMCs with graded IFN-γ responses despite presence of high IL-18BP levels. One representative variant was fused to a anti-PD-1 IgG and demonstrated a tumor growth inhibition of 98% in mouse MC38 tumor model.\nConclusion: We developed a series of engineered IL-18 variants (IL-18v) that fully escape IL-18BP neutralization while providing tunable IL-18R1 affinity. This IL-18v platform enables customizable cytokine potency and supports diverse research and therapeutic applications, including incorporation into fusion proteins, targeted cytokine therapies, and next-generation immunotherapy strategies.", "source_company": "Suzhou Forlong Biotechnology Co., Ltd", "source_org_type": "公司", "row_number": 826, "target_meta": "IL-18R1", "MOA_meta": "其他"}, {"drug_name": "a novel ADC, a PD-L1-mAb conjugated with a topoisomerase-I inhibitor as payload", "company": "Hanx Bio", "org_type": "公司", "target": "PD-L1", "modality": "ADC", "importance_level": "中", "total_score": 73.5, "institution_score": 65, "track_score": 90, "milestone_score": 60, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "靶点为PD-L1的ADC，结合免疫检查点阻断与拓扑异构酶I抑制剂毒力杀伤肿瘤细胞，展现肿瘤特异性及3D模型/体内优于对照ADC的活性。Hanx Bio为国内临床阶段biotech，ADC+PD-L1赛道热度高，但仍处preclinical且内化弱于对照，综合潜力中上。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4538", "id": "DFXM_5wBX1NQZOEH-LS6", "source_drug_name": "a novel ADC, a PD-L1-mAb conjugated with a topoisomerase-I inhibitor as payload", "title": "A novel multi-modal PD-L1-ADC could be a potential BIC candidate treatment for pan-solid tumors with enhanced tumor-specificity", "abstract_text": "PD-L1 is an immune-checkpoint frequently over-expressed oon the surface of many tumor cells, as compared to normal tissues, and it may thus be considered a tumor-associated antigen (TAA), although usually not considered a good one due to wide expression among many normal tissues. Immuno-checkpoint inhibitors (ICIs), e.g. mAbs against PD-L1 and its binding partner, PD1 on effector T-cells within tumors (TIL-Teff), become powerful modality to treat cancers. However, only 15~30% of patients across different cancers responded to PD-(L)1 ICIs whereas most of them eventually relapse and become resistant. Combination therapies, e.g. ICIs plus chemotherapies, have been proven productive with significant clinical benefit in overall survival (OS) and have become standard practice. Chemotherapy usually comes with severe side-effects with narrow therapeutic window (TW). In recent years, ADC, as a new generation of chemo-modality with significantly improved TW due to tumor targeting specificity, witnessed great success in clinics. We hypothesized that an ADC targeting PD-L1, combining specific tumor-targeting and/or ICI, could become a new powerful multi-modality treatment of cancers, superior to existing single-modal chemotherapy or ICI. To test this, we have created a novel ADC, a PD-L1-mAb conjugated with a topoisomerase-I inhibitor as payload, which is being tested for its anti-tumor activity in preclinical settings. Specifically, although specifically binds to several PD-L1-expressing tumor cell lines with high affinity, its naked antibody exhibited poor internalization in PD-L1+ cells. The ADC showed poor cytotoxicity induction in these cells as compared to FIC SGN-PDL1V that internalized efficiently. However, in contrast, the ADC demonstrated robust cytotoxicity in PD-L1+ 3D-tumor organoids in vitro, as well as robust antitumor activity in xenograft models in vivo, even stronger than SGN-PDL1V and significantly superior to the cytotoxicity seen in 2D-cell culture. This interesting discrepancy seen between 2D cell culture and “tumor” (3D-organoid or xenograft tumor) may imply added tumor-specificity, in addition to the differential PD-L1 expression between tumors and normal tissues. It is believed that this ADC maximized its immunomodulation as well as cancer cell killing, along with the observed “tumor-specificity”, which may implicating a potential “BIC” PD-L1-ADC for treating pan-solid tumors with enhanced TW.\nReference Xu, X., et al., A living biobank of matched pairs of patient-derived xenografts and organoids for cancer pharmacology. PLoS One, 2023. 18(1): p. e0279821.", "source_company": "Hanx Bio", "source_org_type": "公司", "row_number": 840, "target_meta": "PDL1", "MOA_meta": "抗体偶联药物"}, {"drug_name": "CSPG4 CAR-T cells", "company": "Cedars-Sinai Medical Center", "org_type": "医院", "target": "CSPG4", "modality": "CAR", "importance_level": "中", "total_score": 73.5, "institution_score": 65, "track_score": 85, "milestone_score": 70, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "靶向CSPG4的CAR-T细胞针对chordoma实体瘤，联合局部透明质酸酶改善ECM屏障增强浸润和杀伤活性。机构为知名美国医院但非头部药企得65分，CAR-T在实体瘤热门赛道且CSPG4为新兴靶点得高track分，体外/类器官/体内模型显示显著协同疗效属较强preclinical里程碑，chordoma罕见瘤未满足需求高故综合热度好，总分中偏高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10799", "id": "rJ3ECZ0B4z9FlvORyiZD", "source_drug_name": "CSPG4 CAR-T cells", "title": "Localized co-delivery of hyaluronidase enhances CSPG4 CAR-T cells cytotoxicity against chordoma", "abstract_text": "Background: Chordoma is a rare malignant bone tumor characterized by a dense extracellular matrix (ECM) and an immunologically “cold” microenvironment that limits immune cell infiltration and therapeutic efficacy. Chondroitin sulfate proteoglycan 4 (CSPG4) has emerged as a promising tumor-associated antigen in chordoma. However, the hyaluronan-rich ECM forms a physical and biochemical barrier that hampers CAR-T cell trafficking and function. We hypothesized that localized co-delivery of hyaluronidase (PH20) could remodel the ECM and enhance the cytotoxic activity of CSPG4-directed CAR-T cells.\nMethods: CSPG4 CAR-T cells were generated using a third-generation lentiviral construct containing CD28-Ox40-CD3ζ signaling domains. Human chordoma cell lines and patient-derived 3D organoids were used to evaluate cytotoxicity and infiltration. Electrical impedance assays were applied to monitor real-time changes in surface charge and cell-matrix interactions following PH20 treatment. Transwell migration assays and 3D organoid co-cultures were used to assess CAR-T infiltration, and cytokine secretion was quantified by ELISA. In vivo efficacy and safety were examined in xenograft models following localized co-delivery of PH20 and CAR-T cells.\nResults: CSPG4 CAR-T cells exhibited antigen-specific cytolytic activity against chordoma cells, but their infiltration was markedly restricted in hyaluronan-rich environments. Electrical impedance analysis revealed that PH20-mediated ECM degradation significantly altered the charge distribution and impedance profile, indicating reduced matrix density and improved accessibility for CAR-T cells. In Transwell assays, PH20 enhanced CSPG4 CAR-T transmigration across hyaluronan-containing barriers. Similarly, in 3D chordoma organoids, PH20 co-treatment promoted deeper CAR-T infiltration and led to greater cytotoxicity with elevated IFN-γ and Granzyme B production. Consistent findings were observed across multiple patient-derived organoid models. In xenograft studies, localized co-delivery of PH20 with CSPG4 CAR-T cells resulted in stronger tumor regression and prolonged survival compared with CAR-T monotherapy (p < 0.01), without observable systemic toxicity.\nConclusion: ECM degradation through localized hyaluronidase co-delivery effectively enhances CSPG4 CAR-T cell infiltration and cytotoxicity against chordoma. This combinatorial approach overcomes stromal barriers, reshapes the tumor microenvironment, and represents a feasible strategy to improve CAR-T efficacy in solid tumors with dense ECM architecture.", "source_company": "Cedars-Sinai Medical Center", "source_org_type": "医院", "row_number": 1088, "target_meta": "CSPG4", "MOA_meta": "其他"}, {"drug_name": "autologous tumor-infiltrating lymphocyte therapy", "company": "Shanghai Juncell Therapeutics Co., Ltd", "org_type": "公司", "target": "未披露", "modality": "CAR", "importance_level": "中", "total_score": 73.5, "institution_score": 65, "track_score": 85, "milestone_score": 75, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "该药物为自体肿瘤浸润淋巴细胞（TIL）疗法，属于细胞治疗热门赛道，Juncell为国内专注TIL的临床阶段biotech，已推进至pivotal Phase II并展示创新制造工艺（长时程冷冻保存种子细胞）。机构为国内新兴biotech非头部，赛道热度高、里程碑验证制造可行性具实用价值，故综合评分中偏上。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9355", "id": "6p7M_5wBZznHJdnt_W3O", "source_drug_name": "autologous tumor-infiltrating lymphocyte therapy", "title": "The \"Preservation & Expansion\" process: A key milestone for enhancing accessibility of autologous tumor-infiltrating lymphocyte therapy by enabling long-term cryopreservation of seed cells", "abstract_text": "Background: Tumor-infiltrating lymphocyte (TIL) therapy has shown promising efficacy in advanced solid tumors. However, its autologous nature poses a major limitation due to the ineligibility of many patients with advanced disease for repeated tumor resections, leading to a loss of potential treatment opportunities. To overcome this challenge, we developed a “Preservation & Expansion” strategy, in which TIL seed cells are generated from initial tumor tissue and cryopreserved for on-demand expansion into final products (FP) upon treatment need.\nObjective: This study aimed to validate the feasibility of expanding FPs from cryopreserved TIL seed cells after various storage durations.\nMethods: Tumor tissues were processed and initially cultured to generate seed cells. Seed cells generated from tumor tissues were either immediately expanded (G0) or cryopreserved for 3 days (G3D), 1, 2, 3, or 6 months (G1M-G6M), or 1 or 2 years (G1Y, G2Y) prior to expansion. Cell viability was assessed at the seed, intermediate, and FP stages. Phenotypic analysis (CD3+, CD8+, CD4+, CD56+) was performed on both seed cells and FPs, while functional analyses, including IFN-γ secretion and cytotoxicity via real-time cell analysis (RTCA), were conducted on the FPs.\nResults: Viability of cells derived from various tumor tissues post-thaw was comparable across different cryopreservation durations, with the following results (%): G0: 79.7±6.4; G3D: 80.9±5.1; G1M: 81.0±5.8; G2M: 80.2±3.9; G3M: 81.3±4.7; G6M: 81.0±5.3; G1Y: 80.4±5.6; G2Y: 80.8±4.8. Moreover, no significant differences in cell viability were observed during the REP culture phase at various time points. Phenotypic characterization by flow cytometry revealed similar profiles among seed cells cryopreserved for different durations and their corresponding final cellular products. Furthermore, cryopreservation duration had minimal impact on the effector functions of the final products, as evidenced by well-maintained levels of IFN-γ secretion and cytotoxic activity across all groups. IFN-γ secretion levels (ng/ml) were: G0: 14.5±7.0; G3D: 15.0±4.2; G1M: 13.4±5.0; G2M: 14.8±5.0; G3M: 16.5±5.0; G6M: 16.5±5.0; G1Y: 16.9±5.0; G2Y: 20.4±5.0. Cytotoxicity assessed by RTCA (%) was as follows: G0: 76.8±7.9; G3D: 78.1±4.3; G1M: 78.3±8.9; G2M: 77.4±9.0; G3M: 79.2±8.3; G6M: 79.9±3.7; G1Y: 77.2±8.7; G2Y: 83.2±3.6.\nConclusion: TIL seed cells can be effectively expanded into functional FPs with consistent viability, phenotype, cytokine secretion, and cytotoxicity after long-term cryopreservation up to two years. These results validate the \"Preservation & Expansion\" process as a robust and feasible approach to improve the accessibility and practicality of autologous TIL therapy by decoupling tumor resection from treatment timing.", "source_company": "Shanghai Juncell Therapeutics Co., Ltd", "source_org_type": "公司", "row_number": 1115, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "BC602", "company": "Dragon Boat Biopharmaceutical", "org_type": "公司", "target": "LGR5xEGFR", "modality": "bispecific antibody", "importance_level": "中", "total_score": 73.5, "institution_score": 65, "track_score": 85, "milestone_score": 70, "field_heat_score": 75, "bonus_score": 3, "brief_reason": "BC602为LGR5×EGFR双特异性抗体，通过增强EGFR内吞降解及ADCC发挥优于单靶EGFR抗体的抗肿瘤活性。机构为国内创新生物药公司（非头部TOP），双抗赛道及EGFR相关肿瘤热门但LGR5非顶级靶点，处于IND-enabling阶段数据较扎实，总分中等偏上。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4376", "id": "hlXM_5wBX1NQZOEH-LK6", "source_drug_name": "BC602", "title": "BC602: An IND-enabling stage LGR5x EGFR bispecific antibody with superior anti-tumor efficacy in mouse CDX and PDX models", "abstract_text": "Epidermal growth factor receptor (EGFR) is a key driver oncogene in the tumorigenesis of many cancer types. EGFR targeting antibodies are approved mainly in EGFR overexpression cancers including colorectal cancer (CRC), head and neck squamous carcinoma (HNSCC), and squamous non-small cell lung cancer (NSCLC). These antibodies exert their function by binding to the extracellular domain(s) to block ligand binding and to induce receptor internalization and degradation. To further enhance EGFR internalization and degradation, we developed an asymmetric LGR5*EGFR bispecific antibody (BsAb) BC602, with one arm as VHH targeting leucine-rich repeat-containing G-protein coupled receptor 5 (LGR5), and the other arm as Fab targeting EGFR. To further increase the anti-tumor activity, BC602 Fc is engineered for enhanced FcγRIII binding and ADCC activity. In ELISA and BLI assays, BC602 binds to the LGR5 protein and EGFR protein with high affinity, respectively. In LGR5 and EGFR expressing cell lines,BC602 showed high binding affinity to cell surface receptors at single digit nM, while isotype control antibody showed no binding. In the pH-rodo internalization assay, BC602 induced significantly higher internalization magnitude than EGFR antibody or LGR5 antibody alone in both cell lines. In growth inhibition assay using the patient-derived organoids (PDO), BC602 showed potent inhibitory activity, much stronger than EGFR antibody. The antitumor efficacy of BC602 was studied in several mouse CDX and PDX models. BC602 demonstrated dose-dependent anti-tumor efficacy, with the antitumor efficacy stronger than EGFR antibody, superior or comparable to its competitor in clinical development stage. In AGS mouse xenograft tumor model, BC602 at 5 mg/kg showed a TGI of 72% while EGFR antibody had a TGI of 50%. In A431-LGR5 mouse xenograft tumor model, BC602 at 1/3/10 mg/kg showed TGI of 42%, 67%, and 83% respectively. BC602 showed no effect on mouse body weight or showed any other safety concerns in these mouse models. BC602 demonstrated good physicochemical properties for CMC, with a high production yield. Non-clinical GLP PK and toxicity studies of BC602 and 200L scale clinical batch production are ongoing. IND filing is expected in 2026 Q3, and the planned indications include cancer types that overexpress both EGFR and LGR5 including HNSCC and CRC.", "source_company": "Dragon Boat Biopharmaceutical", "source_org_type": "公司", "row_number": 1275, "target_meta": "LGR5,EGFR", "MOA_meta": "双特异性抗体"}, {"drug_name": "TGI-17b", "company": "Hefei TG ImmunoPharma Co., Ltd.", "org_type": "公司", "target": "PD-1/VEGF/IL-2Rα", "modality": "trispecific antibody", "importance_level": "中", "total_score": 73.3, "institution_score": 55, "track_score": 92, "milestone_score": 65, "field_heat_score": 85, "bonus_score": 8, "brief_reason": "TGI-17b为潜在first-in-class的PD-1/VEGF/IL-2α-bias三特异性抗体，靶向热门免疫+血管生成+IL-2偏向通路，在preclinical模型中显示优于双抗的抗瘤活性和更好安全性。国内新兴biotech公司，热门trispecific赛道+多靶点组合机制获高赛道分和bonus，但机构与临床里程碑仍有限。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4519", "id": "WlXM_5wBX1NQZOEH-LK6", "source_drug_name": "TGI-17b", "title": "TGI-17b: A potential first-in-class PD-1/VEGF/IL-2α-bias trispecific antibody and the potential next generation cornerstone for pan-cancer therapy", "abstract_text": "Background: Immune checkpoint inhibitors (ICIs) have revolutionized the treatment of solid tumors. However, their efficacy is often limited by resistance, remaining a major therapeutic challenge for many patients. Various next-generation immuno-oncology (IO) therapeutics are under extensive investigation. Among these, PD-1/VEGF and PD-1/IL-2α-bias bispecific antibodies have demonstrated promising efficacy in patients with ICI-resistant and immunologically \"cold\" tumors.To build upon these advances, we developed TGI-17b, a trispecific antibody combined of PD-1/VEGF/IL-2α-bias. TGI-17b demonstrated superior anti-tumor efficacy compared to either PD-1/VEGF or PD-1/IL-2α-bias alone in preclinical models, positioning it as a potential next generation cornerstone therapy for pan-cancer applications.\nMethods: The binding affinity of TGI-17b for PD-1, VEGF, IL-2Rα, and IL-2Rβγ was evaluated using Surface Plasmon Resonance (SPR). Its in vitro functional activity was assessed by measuring the blockade of PD-1/PD-L1, VEGF/VEGFR1 and VEGF/VEGFR2 interactions. Toxicity was evaluated by intravenous administration of a murine surrogate antibody (mPD-1/VEGF/IL-2α-bias) in wild-type mice, compared with a clinical-stage competitor's murine surrogate (mPD-1/IL-2α-bias). The anti-tumor efficacy of TGI-17b was investigated in MC38 and B16F10 syngeneic tumor models using humanized PD-1 transgenic mice.\nResults: TGI-17b exhibited high affinity for VEGF (0.86 nM) and intermediate affinity for IL-2Rα (KD = 24.3 nM), with minimal binding to IL-2Rβγ, confirming its pronounced IL-2Rα-bias character. In functional assays, TGI-17b blocked PD-1/PD-L1 interaction with a slightly higher EC50, and blocked VEGF/VEGFR1 and VEGF/VEGFR2 interactions with significantly lower EC50 values compared to AK112, a PD-1/VEGF bispecific antibody (PD-1/PD-L1 blockade EC50: 0.70 µg/mL for TGI-17b vs. 0.32 µg/mL for AK112; VEGF/VEGFR1 blockade EC50: 0.37 µg/mL vs. 3.53 µg/mL; VEGF/VEGFR2 blockade EC50: 1.29 µg/mL vs. 7.71 µg/mL). In toxicity studies, TGI-17b surrogate demonstrated a favorable safety profile at 40 mg/kg (IV, twice weekly), whereas the competitor's surrogate mPD-1/IL-2α-bias antibody was lethal at 5 mg/kg.In the in vivo efficacy studies, TGI-17b showed superior anti-tumor activity compared to the PD-1/VEGF bispecific antibody in the MC38 model. In the B16F10 model, its efficacy substantially exceeded that of both the PD-1/VEGF and PD-1/IL-2α-bias bispecific antibodies.\nConclusions: These results indicate that TGI-17b, a potential first-in-class PD-1/VEGF/IL-2α-bias trispecific antibody, possesses compelling anti-tumor efficacy and a favorable safety profile in preclinical models. This robust evidence supports its further clinical development as a promising therapeutic candidate for pan-cancer applications.", "source_company": "Hefei TG ImmunoPharma Co., Ltd.", "source_org_type": "公司", "row_number": 147, "target_meta": "PD1,VEGF-A,IL-2Rα", "MOA_meta": "三特异性抗体"}, {"drug_name": "stem cell-derived therapeutic cells", "company": "Evotec International GmbH", "org_type": "公司", "target": "未披露", "modality": "CAR", "importance_level": "中", "total_score": 73, "institution_score": 75, "track_score": 85, "milestone_score": 50, "field_heat_score": 80, "bonus_score": 0, "brief_reason": "该项工作聚焦免疫屏蔽的干细胞来源治疗细胞（疑似iPSC-derived allogeneic cell therapy如CAR或免疫细胞），靶点未明确披露，属于细胞治疗热门赛道。Evotec作为全球知名biotech/CRO有较强平台能力，但本摘要仅为模型验证而非药物具体数据，开发阶段偏preclinical早期导致总分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9367", "id": "WJ7M_5wBZznHJdnt_W3O", "source_drug_name": "stem cell-derived therapeutic cells", "title": "Adapting and validating a humanized mouse model for testing of immune-shielded genetic modifications in therapeutic cells", "abstract_text": "Introduction: Allogeneic transplantation of “off-the-shelf” cell therapies offers a transformative approach for treating a wide range of diseases, including various oncological diseases. However, host-mediated immune rejection ‘’Allogeneic rejection’’ remains a critical barrier to therapeutic success. To address this, immune shielding strategies have been developed to evade immune detection, necessitating robust in vivo models for evaluating their protection from immune cells. Many in vivo models fall short in mimicking the human host immune milieu. We have established a model that incorporates multiple transplantation sites for therapeutic cells, such as under the kidney capsule of the mice. Additionally, we have characterized relevant readouts for the evaluation of the survival of immune-shielded therapeutic cells and monitoring allogeneic rejection.\nMethods: We utilized the immunodeficient BRGSF mice. These mice were humanized using CD34+ from distinct human donors, resulting in the BRGSF-HIS mice (purchased from Genoway). We transplanted these mice with therapeutic stem cell-derived cells. Post-transplantation, mice received human FLT3 ligand to enhance human myeloid cell development. At the end of the study, blood, spleen, and kidney tissues are collected for flow cytometry, MSD cytokine profiling, and histology. Other functional readouts were performed during the in-life phase.\nResults: The model was validated by transplanting wild-type (non-immune shielded) stem cell-derived therapeutic cells under the kidney capsule of BRGSF-HIS mice. In addition, a subset of BRGSF-HIS mice serves as a control group and does not undergo transplantation. The BRGSF-HIS were tested by flow cytometry of blood and spleen to confirm the presence of all the human immune cells essential for allogeneic rejection, including CD4/CD8 T-cells, NK cells, B-cells, monocytes, and M1/M2 macrophages. A comparative analysis was performed on both transplanted and non-transplanted BRGSF-HIS, focusing on the assessment of immune cells and cytokines in the blood and spleen. The transplanted mice exhibited a pronounced pro-inflammatory phenotype in T-cells, characterized by increased CD4+ and CD8+ TEMRA and CD69+ populations, elevated Th1 subsets, and reduced Th2 cells. We observed a tendency for a shift of splenic M2 to M1 macrophages in the transplanted mice. Systemic immune activation was further demonstrated by increased levels of pro-inflammatory cytokines found in both plasma and spleen samples. Histological assessment of immune infiltration at the transplantation site revealed a high abundance of human T-cells, accompanied by macrophages.\nConclusion: We developed a model to evaluate allogeneic rejection of immune-shielded therapeutic cells, assess their survival, and analyze immunophenotyping resulting from transplantation, as well as human host immune infiltration.", "source_company": "Evotec International GmbH", "source_org_type": "公司", "row_number": 84, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "JLC062", "company": "Jecho Institute / Jecho Laboratories", "org_type": "公司", "target": "B7-H3/PD-L1", "modality": "bsADC", "importance_level": "中", "total_score": 73, "institution_score": 55, "track_score": 90, "milestone_score": 65, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "JLC062为双特异性ADC同时靶向B7-H3和PD-L1，结合靶向细胞毒性和免疫检查点阻断机制，具有协同抗肿瘤潜力。机构为中美布局的中小型创新biotech，非头部MNC，赛道为热门bsADC+热门靶点，preclinical阶段动物模型显示优于单药，但尚未进入临床。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9470", "id": "blXM_5wBX1NQZOEH-LS6", "source_drug_name": "JLC062", "title": "Rational design of a B7-H3/PD-L1 bsADC combining checkpoint blockade with targeted cytotoxicity for improved antitumor efficacy", "abstract_text": "B7-H3 (CD276) is a transmembrane glycoprotein of the B7 family aberrantly overexpressed across diverse solid tumors with limited expression in normal tissues, making it an appealing therapeutic target. In addition to potential immunosuppressive effects on T cells, B7-H3 possesses non-immune regulatory functions in enhancing tumor proliferation, angiogenesis, and therapy resistance, which contribute to aggressive disease progression and poor prognosis. PD-L1, another member of the B7 family with clinically validated immune checkpoint function, is frequently co-expressed with B7-H3 in multiple tumor types. Although B7-H3-targeted antibody-drug conjugates (ADCs) and PD-1/PD-L1 checkpoint inhibitors have shown clinical benefit, therapeutic resistance and limited efficacy in “cold” tumors remain challenges. Co-expression of B7-H3 and PD-L1 creates an opportunity to pair targeted cytotoxic delivery with checkpoint blockade. Moreover, the ability of ADCs to induce immunogenic cell death provides additional rationale for integrating ADCs with immune-oncology therapy to enhance antitumor immunity.\nGuided by this rationale, we developed a bispecific ADC (bsADC), JLC062, that engages both B7-H3 and PD-L1. Several anti-B7-H3 antibodies were identified from our fully human naïve phage library, recognizing different epitopes with varying affinities and internalization rates. Fast-internalizing anti-B7-H3 antibodies were formatted as IgGs to enable efficient intracellular delivery, which results in potent in vitro cytotoxicity across cancer cell lines with varying B7-H3 expression. A high-affinity PD-L1 binder, also isolated from our library, was fused to the C-terminus of the anti-B7-H3 IgG Fc as an scFv. It exhibited robust PD-1/PD-L1 blocking activity and induced IL-2 and IFN-γ secretion levels comparable to the clinical benchmark avelumab in a mixed lymphocyte reaction assay. Importantly, this anti-PD-L1 arm was intentionally selected as an antibody with minimal internalization to limit toxicity toward immune cells. In a syngeneic mouse model, JLC062 demonstrated significantly greater antitumor efficacy than either parental monotherapy, anti-PD-L1 antibody or anti-B7-H3 ADC, with no observed body weight loss. These findings highlight JLC062 as a promising therapeutic modality that integrates immune checkpoint inhibition with targeted cytotoxic delivery to yield deep and durable antitumor responses.", "source_company": "Jecho Institute\nJecho Laboratories", "source_org_type": "公司\n研究机构", "row_number": 128, "target_meta": "CD276,PDL1", "MOA_meta": "抗体偶联药物"}, {"drug_name": "ABK-CDK4", "company": "Abbisko Therapeutics", "org_type": "公司", "target": "CDK4", "modality": "inhibitor", "importance_level": "中", "total_score": 73, "institution_score": 75, "track_score": 80, "milestone_score": 60, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "ABK-CDK4为高度选择性脑渗透CDK4抑制剂，靶向CDK4并显著降低CDK6抑制以改善治疗窗，尤其针对乳腺癌脑转移未满足需求。Abbisko作为国内临床阶段biotech（有管线进入FDA NDA并有国际合作），赛道热门（选择性CDK4抑制+脑渗透差异化），但仍处preclinical阶段，综合热度较高但里程碑强度有限。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1502", "id": "wFXM_5wBX1NQZOEH-LK6", "source_drug_name": "ABK-CDK4", "title": "Discovery of ABK-CDK4, a selective and brain-penetrant CDK4 inhibitor", "abstract_text": "Introduction: Cyclin-dependent kinase (CDK)4/6 play important roles in the G1-S phase transition in the cell cycle. Although the first generation dual CDK4/6 inhibitors— such as palbociclib, ribociclib, and abemaciclib—have demonstrated clinical efficacy in advanced breast cancer, inhibition of CDK6 would cause dose-limiting hematological toxicity. Sparing CDK6 inhibition could improve therapeutic window and enhance CDK4 target coverage. Meanwhile, brain metastases occur in 20%-40% of patients with breast cancer during their course of disease. A selective CDK4 inhibitor with reduced CDK6 inhibition and good brain penetration could provide a differentiated therapeutic option, especially for patients with brain metastasis. Through advanced computational structural analysis and medicinal chemistry effort, we have discovered ABK-CDK4, a highly selective and brain-penetrant CDK4 inhibitor. Preclinical studies demonstrate its good selectivity over CDK6, robust anti-tumor efficacy, and favorable pharmacokinetics.\nMethods: Biochemical assays were performed to assess the potency of ABK-CDK4 against CDK4 and to evaluate selectivity across a kinase panel, including CDK6. Anti-proliferative effect and inhibition of retinoblastoma (Rb) phosphorylation were tested in multiple cancer cell lines. In vivo anti-tumor activity was evaluated in cell-derived xenograft (CDX) mouse models. Pharmacokinetic and safety profiles were also examined.\nResults: ABK-CDK4 exhibited potent inhibition of CDK4 with >70-fold selectivity over CDK6. In HR+HER2- cancer cell lines, it effectively suppressed Rb phosphorylation and cell proliferation. ADME profiling demonstrated superior brain-penetration (Kpuu>0.5) and favorable drug-like properties. Orally administration of ABK-CDK4 led to robust tumor growth inhibition in HR+HER2- breast cancer xenograft models.\nConclusion: ABK-CDK4, developed by Abbisko Therapeutics, is a highly selective and brain-penetrant CDK4 inhibitor with the potential to address limitations of current CDK4/6 inhibitors. Its promising efficacy, selectivity, and other properties support further preclinical advancement toward clinical development.", "source_company": "Abbisko Therapeutics", "source_org_type": "公司", "row_number": 221, "target_meta": "CDK4", "MOA_meta": "抑制剂"}, {"drug_name": "vizenpistat", "company": "Stingray Therapeutics", "org_type": "公司", "target": "ENPP1", "modality": "inhibitor", "importance_level": "中", "total_score": 73, "institution_score": 65, "track_score": 85, "milestone_score": 65, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "vizenpistat为口服ENPP1抑制剂，通过阻断cGAS-STING通路负调控激活先天免疫抗肿瘤响应。Stingray Therapeutics为临床阶段小型biotech公司（非头部MNC），赛道热门（ENPP1/STING相关免疫治疗），处于Phase 1b/2联合用药阶段但摘要未公开具体数据，综合潜力中等偏上。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/12241", "id": "w1XM_5wBX1NQZOEH-LK6", "source_drug_name": "vizenpistat", "title": "A progress report for a Phase 1b/2 study of ENPP1 inhibitor, vizenpistat in combination with botensilimab and balstilimab in subjects with refractory metastatic microsatellite stable colorectal cancer", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Stingray Therapeutics", "source_org_type": "公司", "row_number": 222, "target_meta": "ENPP1", "MOA_meta": "抑制剂"}, {"drug_name": "BCG029", "company": "Biocytogen", "org_type": "公司", "target": "ADAM9", "modality": "ADC", "importance_level": "中", "total_score": 73, "institution_score": 75, "track_score": 80, "milestone_score": 60, "field_heat_score": 75, "bonus_score": 3, "brief_reason": "BCG029为靶向ADAM9的ADC，采用新型Top1抑制剂payload，在PDX模型中显示出强效抗肿瘤活性。Biocytogen作为国内知名biotech平台公司，ADC赛道+新兴靶点ADAM9热度较高，但仍处于preclinical阶段且ADAM9非最热门靶点，整体重要性中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4473", "id": "BlXM_5wBX1NQZOEH-LO6", "source_drug_name": "BCG029", "title": "An ADAM9-targeting ADC featuring a novel topoisomerase I inhibitor payload demonstrated potent efficacy in PDX models", "abstract_text": "ADAM9 (A disintegrin and metalloprotease 9) is a membrane-anchored protein that is crucial for various physiological functions, mainly through its disintegrin domain for adhesion and metalloprotease domain for ectodomain shedding of cell surface proteins. Its overexpression in various cancers, including pancreatic, esophageal, breast, gastric, lung, and colorectal cancers, is linked to increased tumor aggressiveness and poor prognosis. Although ADAM9 is a promising target for ADC development, its expression in human tissues and immune cells, such as monocytes, macrophages, and neutrophils, poses challenges. This overlapping expression raises the risk of off-target effects and toxicity to normal tissues, which may hinder the efficacy and safety of ADC therapies targeting ADAM9.\nTherefore, we have developed an ADAM9 clone, Ab.01, utilizing the fully human RenLite ADAM9 knockout (KO) mice. Ab.01 specifically binds to the membrane-proximal region of ADAM9-L while disregarding the secreted isoform, ADAM9-S. This clone targets ADAM9 without cross-reactivity to other ADAM family members, a specificity confirmed using an ADAM9 KO cell line. Additionally, Ab.01 demonstrated broad binding activity to a panel of cancer cell lines. Ab.01 also showed effective internalization activity. Furthermore, in a PBMC binding assay, Ab.01 demonstrated minimal binding activity to myeloid cells compared to the benchmark antibody. This observation suggests that Ab.01 may reduce off-target interactions, underscoring its potential for improved specificity in therapeutic applications.\nAb.01 conjugated to vcMMAE showed superior efficacy in several PDX models compared to benchmark antibodies conjugated with the same payload. Ab.01 was then conjugated with BLD1102, a novel Top1 inhibitor, resulting in BCG029, which demonstrated potent efficacy in PDX models. Ongoing in vivo studies are continuing to evaluate the performance of BCG029.\nThese findings underscore the therapeutic potential of BCG029 in targeting solid tumors that express ADAM9. By targeting ADAM9 specifically, BCG029 could provide a safer and more effective treatment option for patients with ADAM9-expressing tumors.", "source_company": "Biocytogen", "source_org_type": "公司", "row_number": 230, "target_meta": "ADAM9", "MOA_meta": "抗体偶联药物"}, {"drug_name": "compound A", "company": "Deciphera Pharmaceuticals, LLC", "org_type": "公司", "target": "colchicine binding site of tubulin", "modality": "inhibitor", "importance_level": "中", "total_score": 73, "institution_score": 80, "track_score": 65, "milestone_score": 70, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "Compound A为口服微管去稳定剂，靶向colchicine结合位点，在KRAS突变模型中显示单药抗肿瘤活性。Deciphera作为头部biotech（现隶属Ono）机构实力强，但微管靶向剂赛道非当前最热门，preclinical阶段有较好PD/PK和疗效数据但无临床里程碑。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8757", "id": "xp7M_5wBZznHJdnt_W3O", "source_drug_name": "compound A", "title": "Discovery of a novel orally available microtubule-destabilization agent that targets the colchicine binding site and exhibits antitumor activity in KRAS-mutant models", "abstract_text": "Background: Microtubules are essential for regulating cell growth, cell division, protein trafficking, and key cell signaling events. Alterations to the microtubule network affect cell survival, thus making microtubule-targeting agents desirable as cancer therapeutic agents. Currently, several tubulin modulators are approved for cancer treatment. However, development of additional microtubule-targeting agents is still needed to improve treatment outcomes, mitigate side effects, and overcome resistance mechanisms. Here, we describe compound A, a novel, orally available microtubule-destabilizing agent that targets the colchicine binding site and exhibits single-agent antitumor activity in KRAS-mutant models.\nMethods: Inhibition of tubulin polymerization was measured using a recombinant polymerization assay and a cell-based microtubule sedimentation assay. Binding to the colchicine site of tubulin was determined by a binding competition assay using a BODIPY-colchicine probe. Disruption of tubulin formation was determined by immunofluorescence of microtubules in A549 cells. Compound binding to the tubulin complex was determined via X-ray crystallography. Cellular proliferation of KRAS-mutant and isogenic cell lines was measured using resazurin. KRAS-mutant mouse xenograft models were used to assess pharmacokinetics (PK), pharmacodynamics, and antitumor activity.\nResults: Compound A binds to the colchicine site and destabilizes tubulin polymerization. Treatment resulted in single-agent inhibition of proliferation of KRAS-mutant cancer cell lines. Immunofluorescence of microtubules in A549 cells revealed disruption of the microtubule network and dysregulated spindle formation. Compound A exhibited a favorable ADME and PK profile. Oral treatment of compound A as a single agent resulted in 56% tumor growth inhibition in a subcutaneously implanted KRAS-mutant lung xenograft model.\nConclusions: Compound A is an orally bioavailable tubulin modulator that binds to the colchicine site and inhibits tumor growth in a KRAS-mutant model as a single agent. Our preclinical data provide proof of concept for the development of an orally available microtubule-destabilizing agent.", "source_company": "Deciphera Pharmaceuticals, LLC", "source_org_type": "公司", "row_number": 274, "target_meta": "microtubule", "MOA_meta": "抑制剂"}, {"drug_name": "Ab.168-vcMMAE", "company": "Biocytogen", "org_type": "公司", "target": "CDCP1", "modality": "ADC", "importance_level": "中", "total_score": 73, "institution_score": 75, "track_score": 80, "milestone_score": 60, "field_heat_score": 75, "bonus_score": 0, "brief_reason": "靶点为CDCP1（C-terminal fragment特异性），ADC modality针对多种实体瘤高表达CDCP1。Biocytogen作为国内头部biotech平台公司，ADC赛道热度高，但项目仍处preclinical PDX模型阶段，里程碑价值中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4470", "id": "5p7M_5wBZznHJdnt_W3O", "source_drug_name": "Ab.168-vcMMAE", "title": "BCG046, a CDCP1 ADC that targets CTF, has demonstrated potent in vitro and in vivo efficacy", "abstract_text": "Background CUB domain-containing protein 1 (CDCP1) is a type I transmembrane glycoprotein that is associated with tumor progression, drug resistance, and a poor prognosis. CDCP1 is highly expressed in various types of cancer, including pancreatic, breast, prostate, ovarian, colorectal, and lung cancers. It is closely tied to patient prognosis. CDCP1 can be cleaved by extracellular proteases, resulting in the shedding of the protein. The presence of these shedding CDCP1 in the serum of cancer patients raises concerns regarding the neutralization of biologic therapeutics.\nResults Thus, we developed the antibody clone Ab.168, which specifically targets the C-terminal fragment (CTF) of CDCP1, utilizing our fully human RenMice platform. Ab.168 exhibited cross-reactivity with human, monkey, and mouse CDCP1, demonstrating a strong affinity for and effective binding to a variety of tumor cell lines. This broad reactivity underscores its potential for use in preclinical development and transition. Additionally, it displayed efficient internalization in cell lines with varying levels of CDCP1 expression, with performance comparable to or better than both the CTF and amino-terminal fragment (ATF) benchmarks. Moreover, Ab.168 exhibited robust development potential, as its binding activity remained unaffected by stress conditions, and it showed no nonspecific binding in polyreaction assays. When conjugated to vcMMAE, Ab.168-vcMMAE demonstrated superior or comparable efficacy to benchmark ADCs in NSCLC and colorectal patient-derived xenograft (PDX) models.\nConclusion These findings underscore the therapeutic potential of Ab.168 in developing an ADC as a promising strategy for treating colorectal cancer and other solid tumors characterized by CDCP1 expression. Further preclinical studies are underway.", "source_company": "Biocytogen", "source_org_type": "公司", "row_number": 276, "target_meta": "CDCP1", "MOA_meta": "抗体偶联药物"}, {"drug_name": "BET degrader", "company": "OBI Pharma, Inc", "org_type": "公司", "target": "BET", "modality": "DAC", "importance_level": "中", "total_score": 73, "institution_score": 65, "track_score": 90, "milestone_score": 55, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "BET degrader通过DAC形式递送实现靶向蛋白降解，靶点为BET家族蛋白；OBI Pharma为台湾临床阶段biotech公司，专注ADC/DAC平台，赛道热门（degrader+ADC结合），但仅in vitro POC阶段，无临床数据。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5401", "id": "YZ7ECZ0BZznHJdntvNYd", "source_drug_name": "BET degrader", "title": "Hydrophilicity-enhanced linker technology enables site-specific degrader-antibody conjugates with improved stability and enhanced activity", "abstract_text": "Proteolysis-targeting chimeras (PROTACs) have emerged as a novel modality for targeted protein degradation, enabling catalytic removal of disease-related proteins rather than transient inhibition. Despite their mechanistic advantages, most PROTACs suffer from poor drug-like properties—high molecular weight, highly hydrophobic, and with limited permeability—leading to suboptimal pharmacokinetics and formulation challenges. To overcome these limitations, the concept of degrader-antibody conjugates (DACs) has recently gained attention, leveraging antibody-mediated delivery to transport degraders selectively into target cells. DACs can reduce systemic exposure and overcome permeability barriers, thereby expanding the therapeutic utility of degraders. However, bioconjugation of PROTAC payloads remains hindered by issues such as antibody aggregation, inefficient conjugation, and constraints in achieving optimal drug-to-antibody ratios (DAR). Here, we selected a representative BET degrader as the proof-of-concept payload to evaluate the feasibility of DAC construction. Leveraging glycan site-specific technology, we achieved DAC construction with tunable DARs and robust conjugate stability. To address the intrinsic physicochemical challenges of PROTACs, proprietary linker technology was incorporated to enhance hydrophilicity and mitigate aggregation. Proprietary linker also provides high serum stability and enables precise release in the tumor site, potentially broadening the therapeutic index. This BET DAC is anticipated to be applicable to both solid and hematologic malignancies. In vitro studies showed that glycan site-specific DACs preserved antibody binding, maintained high stability, and facilitated efficient intracellular delivery of active degraders. Functional analyses confirmed target protein degradation with time- and dose-dependent kinetics, accompanied by strong cytotoxicity in antigen-positive models. These results establish clear proof of concept for our linker-enabled DAC platform. Through the integration of site-specific glycan conjugation and proprietary linker chemistry, this DAC platform offers a versatile and scalable solution to overcome hydrophobic degrader limitations, paving the way for next generation of targeted degradation therapeutics.", "source_company": "OBI Pharma, Inc", "source_org_type": "公司", "row_number": 736, "target_meta": "BET", "MOA_meta": "抗体偶联降解剂"}, {"drug_name": "IL12-VRP", "company": "VLP Therapeutics, Inc.", "org_type": "公司", "target": "未披露", "modality": "other", "importance_level": "中", "total_score": 73, "institution_score": 65, "track_score": 75, "milestone_score": 80, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "IL12-VRP为基于alphavirus replicon的IL-12递送平台，通过重编程肿瘤相关髓系细胞（TAMs和TANs）激活抗肿瘤免疫，无明确药物靶点。VLP Therapeutics作为中小型创新biotech，平台创新性强，已进入I期临床（NCT06736379），多模型显示优异肿瘤控制和免疫记忆。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5132", "id": "b1XM_5wBX1NQZOEH-LS6", "source_drug_name": "IL12-VRP", "title": "Alphavirus replicon expressing IL-12 reprograms tumor-associated macrophages and neutrophils and induces anti-tumor immunity", "abstract_text": "Immunosuppressive myeloid cells such as tumor-associated macrophages (TAMs) and neutrophils (TANs) contribute to resistance against immune checkpoint therapies by fostering a suppressive tumor microenvironment (TME). To overcome this barrier, we developed a single-cycle alphavirus replicon particle (VRP) vector encapsulating self-amplifying RNA (saRNA) encoding interleukin-12 (IL-12) for intratumoral delivery, leveraging the natural tropism of alphaviruses for myeloid cells. The VRP was engineered with a capsid nuclear localization signal mutation to enhance transgene expression and reduce host cell toxicity. In preclinical studies, single-cell RNA sequencing of treated mouse 4T1 breast carcinoma tumors and draining lymph nodes revealed that IL12-VRP preferentially transduced M2-like TAMs and TANs, reprogramming them toward pro-inflammatory phenotypes via interferon signaling. This effect was further amplified by IL-12 expression, leading to expansion of pro-inflammatory Nos2⁺ macrophage and neutrophil populations. IL12-VRP also activated cytotoxic NK and T cells, inducing IFN-γ expression and enhancing anti-tumor immunity. Compared to lipid nanoparticle-based delivery of the same saRNA replicon, IL12-VRP achieved superior tumor control in the MC38 colorectal model with ~1000-fold lower RNA gene copies in the dose. IL12-VRP suppressed MOC2 head and neck model tumor growth, prevented nodal and lung metastases, and remodeled immune landscapes in both tumors and lymphoid tissues. CT26 colorectal carcinoma model mice treated with IL12-VRP exhibited tumor reduction, durable systemic immune memory and rejected subsequent tumor rechallenge. These findings establish IL12-VRP as a potent immunomodulatory platform capable of reprogramming myeloid cells and enhancing adaptive immunity. This approach may improve outcomes in myeloid-dominant TMEs and augment current immunotherapies. Ongoing clinical evaluation (NCT06736379) will determine its translational potential.", "source_company": "VLP Therapeutics, Inc.", "source_org_type": "公司", "row_number": 910, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "DBXO-1", "company": "Deck Bio, Inc.", "org_type": "公司", "target": "multi-pMHC (multiple cancer-restricted peptide-MHC complexes)", "modality": "bispecific T cell engager", "importance_level": "中", "total_score": 72.5, "institution_score": 65, "track_score": 90, "milestone_score": 55, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "DBXO-1为多靶点pMHC双特异性T细胞衔接器，创新解决实体瘤低拷贝数和异质性问题，靶向癌特异性胞内蛋白呈递的pMHC。Deck Bio为早期biotech公司获BMS/Servier Golden Ticket等认可，赛道热门但仍处preclinical，综合潜力中等偏上。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4552", "id": "6lXM_5wBX1NQZOEH-LC5", "source_drug_name": "DBXO-1", "title": "Preclinical characterization of DBXO-1, a multi-pMHC targeted bispecific T cell engager for major solid tumors", "abstract_text": "Bispecific T cell engagers (TCEs) are a well-established therapeutic modality in heme malignancies, and recent regulatory approvals in select solid tumors highlight their promise more broadly. However, adoption in major solid tumor indications and across large patient populations remains limited, in part by the scarcity of surface targets with cancer-exclusive expression patterns. Cancer-specific intracellular targets can be accessed by TCEs via peptide-MHC complexes (pMHCs), but individual pMHCs are expressed at low copy numbers which impacts TCE potency and breadth of response. DBXO-1 is designed to address this limitation by targeting a defined set of cancer-restricted intracellular proteins that generate multiple target pMHCs that can be recognized by a single binder, addressing copy number and heterogeneity concerns. Here, we describe the specificity profile and functional activity of DBXO-1 preclinically.A T cell receptor recognizing HLA-A*02:01-restricted target peptides was affinity- and specificity-engineered using yeast and phage display, aided by structural modelling. Optimized binders were formatted into Fc-containing TCEs using clinically validated anti-CD3 sequences. Affinity was measured by biolayer interferometry. Specificity was characterized using yeast display workflows and a T2/Jurkat reporter assay, cytotoxicity was assessed by LDH release. The DBXO-1 discovery campaign identified multiple pMHC binders with single digit nanomolar affinities to the relevant target pMHCs. When formatted into TCEs, this led to potent T cell activation with EC50s <10 pM. Mutational analyses confirmed a shared structural recognition mode across target pMHCs, underlining the basis for the intended multi-targeting mechanism. Importantly, the specificity of final leads was assessed sequence-agnostically by testing binding against 13,849 HLA-A*02:01-presented peptides that were found in healthy tissues by immunopeptidomics. This comprehensive assessment revealed only a very small number of low-affinity interactions, a profile superior to a clinical stage benchmark pMHC-TCE. When T2 cells were pulsed with these peptides at supraphysiological concentrations for additional stringency, >100x EC50 windows for T cell activation were observed. Further derisking on healthy cells is ongoing. Finally, DBXO-1 mediated potent, dose-dependent cytotoxicity on multiple HLA-A*02:01+ cell lines expressing the target signature, while no activity was observed in absence of either target expression or HLA restriction.Taken together, these data support continued preclinical development of DBXO-1, with the goal of entering a first-in-human clinical trial in 2027. Initial clinical development is anticipated in biomarker-selected patient populations across major solid tumors, including non-small cell lung, head and neck, and gastroesophageal cancers.", "source_company": "Deck Bio, Inc.", "source_org_type": "公司", "row_number": 151, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "ITF3912", "company": "Italfarmaco SpA", "org_type": "公司", "target": "SSTR2", "modality": "PDC", "importance_level": "中", "total_score": 72.5, "institution_score": 65, "track_score": 80, "milestone_score": 75, "field_heat_score": 75, "bonus_score": 3, "brief_reason": "ITF3912为靶向SSTR2的peptide-drug conjugate（PDC），利用duocarmicin毒素实现DNA损伤，针对神经内分泌肿瘤尤其是SSTR2高表达的GEP-NETs和SCLC亚群。Italfarmaco为意大利中型私营制药公司（非头部MNC/biotech），PDC赛道结合热门靶点SSTR2及强效preclinical数据（体外IC50低至4nM、体内显著抑瘤甚至完全缓解）支撑较高赛道与里程碑分，但机构背景限制总分。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4315", "id": "S57M_5wBZznHJdnt_W7P", "source_drug_name": "ITF3912", "title": "Targeted DNA damage through SSTR2: Preclinical development of a novel peptide-drug conjugate for neuroendocrine tumors", "abstract_text": "Targeted induction of DNA damage in tumor cells offers a promising strategy to efficiently kill cancer cells while sparing healthy tissues. Precise tumor targeting can be achieved by the exploitation of the differential expression of specific molecular targets on the surface of tumor cells. Somatostatin receptor 2 (SSTR2) has emerged as a valuable tumor-associated target, due to its high expression in gastroenteropancreatic neuroendocrine tumors (GEP-NETs). SSRT2 is not only expressed in these differentiated, slow-proliferating NET, but also in highly proliferative and metastatic neuroendocrine carcinomas, such as small cell lung cancer (SCLC). SSTR2 overexpression occurs in up to 50% of primary tumors from SCLC patients and is correlated with poor prognosis, highlighting SSTR2 as an optimal candidate for targeted therapeutic intervention in a subset of SCLC patients. To exploit this opportunity, we designed a peptide drug conjugate (PDC), named ITF3912 which combines a modified octreotide analog with a novel and potent duocarmicin via a cathepsin-cleavable linker. In preclinical studies in vitro ITF3912 demonstrated high affinity and selectivity for SSTR2, acting as an agonist with an IC₅₀ of 8 nM and a selectivity index of at least 10 over SSTR3/5, with no significant binding observed for SSTR1 or SSTR4. ITF3912 induced cytotoxicity in SSTR2-expressing cells, with efficacy correlated to SSTR2 expression levels. In high level SSTR2 expressing NCI-H524 cells, ITF3912 was rapidly internalized and localized in lysosomes where enzymatic cleavage of the linker released the active toxin. Once in the nucleus, the toxin induced an S-phase replication block and a potent and lethal DNA damage as evidenced by the activation of key biomarkers such as the phosphorylation of ATM, ATR, CHK1, CHK2, RPA32 and γ-H2AX, leading to cell death with an IC50 of 4 nM. The NCI-H69 cell line that expresses lower level of SSTR2 can still be targeted by ITF3912 but with lower efficiency (60 nM). The activity on NCI-H727 cell line that expresses very low level of SSTR2 diminished as expected (400 nM). Consistent with the in vitro findings, ITF3912 showed strong antitumor efficacy in vivo. It effectively reduced the tumor growth of NCI-H524 with a survival rate of 50% after 80 days of treatment and several mice showed complete tumor remission. In contrast, ITF3912 was less effective on NCI-H727 cell line by inducing a tumor growth reduction of 30%. Collectively, these data establish ITF3912 as a potent and selective SSTR2-targeted PDC, whose efficacy in vitro and in vivo correlates with receptor expression levels. These results support the use of ITF3912 as a therapeutic option for patients with SSTR2-positive neuroendocrine tumors, addressing a significant unmet medical need. Encouraging preliminary toxicology results, further support the progression of ITF3912 toward clinical development.", "source_company": "Italfarmaco SpA\nItalfarmaco S.p.A.", "source_org_type": "公司", "row_number": 155, "target_meta": "SSTR2", "MOA_meta": "其他"}, {"drug_name": "RPT-E-037", "company": "Remedy Plan Therapeutics", "org_type": "biotech", "target": "NAMPT", "modality": "inhibitor", "importance_level": "中", "total_score": 72.5, "institution_score": 75, "track_score": 80, "milestone_score": 60, "field_heat_score": 75, "bonus_score": 3, "brief_reason": "RPT-E-037为新型hyperbolic NAMPT抑制剂，靶向NAD salvage pathway关键酶NAMPT，与pan-RAS抑制剂协同在KRAS突变PDAC模型中显示显著协同抗瘤效应，包括耐药模型。机构为研究机构而非公司导致分数不高，但热门代谢靶点+preclinical协同数据+新型抑制机制获加分，总分处于中偏高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8820", "id": "P57M_5wBZznHJdnt_W3O", "source_drug_name": "RPT-E-037", "title": "Preclinical evaluation of a novel hyperbolic NAMPT inhibitor in combination with pan-RAS targeted therapies in pancreatic ductal adenocarcinoma", "abstract_text": "Background: Pancreatic ductal adenocarcinoma (PDAC) remains highly lethal, driven by near-universal KRAS mutations and profound metabolic dependence on nicotinamide adenine dinucleotide (NAD). NAMPT, the rate-limiting enzyme of the NAD salvage pathway, is frequently upregulated in KRAS-driven tumors, suggesting metabolic co-dependence. We evaluated whether simultaneous blockade of NAMPT and KRAS signaling enhances antitumor efficacy in PDAC.\nMethods: KRAS-NAMPT expression correlations were analyzed in TCGA PDAC samples (n=179). Multiple KRAS-mutant PDAC cellular models, including KRASG12C inhibitor, KRASG12D inhibitor, and pan-RAS inhibitor (RMC6236)-resistant lines were treated with the hyperbolic NAMPT inhibitor RPT-E-037, RMC6236, or both. Antitumor activity was assessed in 2D viability assays, 3D spheroid cultures, and patient-derived 2D/3D co-culture systems. Drug interactions were calculated using combination index (CI) analysis.\nResults: TCGA analysis revealed a fairly strong positive correlation between KRAS and NAMPT expression (Spearman ρ=0.59). RMC6236-resistant PDAC cells displayed increased NAMPT expression and heightened sensitivity to RPT-E-037 compared to parental cells. Similar NAMPT upregulation and enhanced NAMPT inhibitor sensitivity were observed in KRASG12C and KRASG12D inhibitor-resistant models. Across KRAS-mutant PDAC lines, RPT-E-037 combined with RMC6236 produced robust synergy (CI<1) in both 2D and 3D cultures. In patient-derived PDAC co-culture systems, the combination significantly reduced tumor mass, dismantled compact spheroid architecture, and disrupted tumor-stroma interactions more effectively than either agent alone. KRASG12D-mutant metastatic patient rapid autopsy tissue-derived and KPC mice tumor-derived subcutaneous and orthotopic xenograft studies with the combination are ongoing.\nConclusion: Dual inhibition of NAMPT-mediated NAD biosynthesis and KRAS signaling yields synergistic antitumor activity in PDAC, including models resistant to KRAS-targeted therapies. These findings support NAMPT-KRAS co-dependency as a therapeutically actionable vulnerability and justify further translational and in vivo studies to guide clinical development and biomarker-based patient selection.\"Generative AI was used for improving the language of the abstract\".", "source_company": "Karmanos Cancer Institute", "source_org_type": "研究机构", "row_number": 264, "target_meta": "NAMPT", "MOA_meta": "抑制剂"}, {"drug_name": "Hit Synergy platform", "company": "Sygnature Discovery", "org_type": "公司", "target": "未披露", "modality": "other", "importance_level": "中", "total_score": 72.5, "institution_score": 65, "track_score": 75, "milestone_score": 80, "field_heat_score": 70, "bonus_score": 5, "brief_reason": "Hit Synergy platform为Sygnature Discovery的集成hit识别技术平台，用于挑战性肿瘤靶点快速产生高质量多样性hits，未明确具体靶点和药物modality。机构为专业CRO而非MNC/biotech所有者得65分，平台加速发现流程体现pre-candidate阶段里程碑价值较高得80分，综合热度和创新加速加分后总分中位。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6513", "id": "R57ECZ0BZznHJdntvNYd", "source_drug_name": "Hit Synergy platform", "title": "DiscoveryDirect: Extending direct-to-biology paradigms to accelerate oncology drug discovery", "abstract_text": "The average timeline from project initiation to preclinical candidate delivery in oncology drug discovery is approximately four years. To compress these timelines, direct-to-biology strategies are increasingly employed to expedite early decision-making and compound progression. However, conventional approaches often remain limited to biophysical off-rate assessments of crude reaction mixtures (CRMs), restricting their utility. To overcome these constraints, we have expanded this paradigm through integrated methodologies, including Direct-to-Crystallography (D2C), to validate hits and elucidate structure-activity relationships (SAR), enabling pre-candidate delivery in as little as 18 months.\nHarnessing our Hit Synergy platform which combines complementary screening technologies, we rapidly generated novel, high quality and structurally diverse hits for a challenging and clinically relevant oncology target. Early deployment of D2C, using existing HTS liquid stocks, delivered ligand-bound structures without delays associated with hit re-synthesis or re-acquisition. These structures confirmed target engagement and revealed novel binding interactions. Orthogonal hit validation employed direct-to-biology approaches such as off-rate screening, alongside tailored biochemical and cellular assays on purified samples.\nIntegration of structural insights and biological data accelerated hit expansion via high-throughput chemistry (HTC) and complementary direct-to-biology assays validated for both pure compounds and CRMs. Robust D2C determinations from CRMs yielding as little as 15% product further streamlined SAR generation and hypothesis testing, influencing medicinal chemistry design and decision making and compressing the design-make-test cycle. Generative AI-driven idea generation and direct-to-physicochemical assays further supported optimization for developability.\nTogether, this fully integrated, multi-modal workflow enabled rapid, holistic decision-making at critical project stages, delivering pre-candidate quality derivatives in a significantly truncated timeframe. By embedding direct-to-discovery methodologies throughout the pipeline, we successfully accelerated progression from hit identification to candidate selection, advancing novel therapeutics toward the clinic with unprecedented efficiency.", "source_company": "Sygnature Discovery", "source_org_type": "公司", "row_number": 537, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "DDR1 inhibitors", "company": "Cureverse Inc.", "org_type": "公司", "target": "DDR1", "modality": "inhibitor", "importance_level": "中", "total_score": 72.5, "institution_score": 75, "track_score": 80, "milestone_score": 60, "field_heat_score": 75, "bonus_score": 3, "brief_reason": "靶点为DDR1的小分子抑制剂，通过重编程胶原-DDR1肿瘤微环境发挥抗肿瘤作用，具有克服KRAS抑制剂耐药和改善免疫微环境的潜在新机制。公司为韩国新兴biotech，有海外授权成功案例和融资，但非头部；赛道为肿瘤微环境调控+新兴靶点，preclinical阶段展示AACR，亮点为first-in-class潜力。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11458", "id": "AlXM_5wBX1NQZOEH-LO6", "source_drug_name": "DDR1 inhibitors", "title": "Discovery of highly selective, orally available small-molecule DDR1 inhibitors that reprogram the collagen-DDR1 tumor microenvironment", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Cureverse Inc.", "source_org_type": "公司", "row_number": 655, "target_meta": "DDR1", "MOA_meta": "抑制剂"}, {"drug_name": "EFTX-G12V-pTEAD", "company": "EnFuego Therapeutics Inc", "org_type": "公司", "target": "KRAS G12V 和 pan-TEAD", "modality": "siRNA", "importance_level": "中", "total_score": 72, "institution_score": 65, "track_score": 90, "milestone_score": 55, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "该药为EGFR靶向的嵌合siRNA，同时沉默KRAS G12V和pan-TEAD以克服KRAS抑制剂耐药，靶点和机制创新性强。EnFuego为早期美国biotech公司，赛道（KRAS+TEAD+RNAi）热度高但仍处preclinical规划阶段，综合潜力中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5072", "id": "K1XM_5wBX1NQZOEH-LO6", "source_drug_name": "EFTX-G12V-pTEAD", "title": "Synergistic co-targeting of KRAS G12V and pan-TEAD by an EGFR-directed, inverted chimeric RNAi molecule", "abstract_text": "While KRAS has long been considered an “undruggable” oncoprotein, advancements in structural and chemical biology have resulted in KRAS G12C, G12D, pan-KRAS and pan-RAS small molecule inhibitors. Although several have shown clinical promise, therapeutic resistance remains a significant problem. Recently, YAP/TAZ activation has emerged as a common resistance mechanism to KRAS inhibition. YAP and TAZ act as transcription coactivators with the TEAD1-4 transcription factors as part of the Hippo signaling pathway. Several groups have already shown that pan-TEAD (pTEAD) inhibition synergizes with KRAS inhibition, and YAP and KRAS exhibit pathway crosstalk in cancer. Previously, we developed EFTX-G12V, a first-in-class EGFR-directed KRAS G12V selective siRNA that displays excellent single agent efficacy in lung, colon and pancreatic cancers. Further, we developed a novel inverted chimeric siRNA design that incorporates two oncogene-targeting siRNAs linked by an endo-nucleolytic DNA bridge. The chimeric siRNA design ensures equivalent molar targeting of both gene transcripts in the same cell with enhanced metabolic stability and tumor accumulation. Here, we describe the development of chemically modified pTEAD targeting siRNAs and subsequent development of a KRAS G12V, pTEAD targeting chimeric siRNA. We used a structure-activity relationship screening approach to identify a highly potent fully chemically modified siRNA that inhibits TEAD1-4 at both the mRNA and the protein level. This pTEAD siRNA inhibited cancer cell growth in vitro and showed no concerning off-target effects. Using this siRNA and EFTX-G12V we developed EFTX-G12V-pTEAD, that inhibits KRAS G12V, TEAD1-4 and downstream signaling at both the mRNA and the protein level. Importantly, EFTX-G12V-pTEAD showed improved inhibition of downstream targets when compared to each single agent siRNA highlighting the value of the chimeric siRNA. Similar to our previously described siRNAs, EFTX-G12V-pTEAD is conjugated to an EGFR linear ligand that enables high tumor-to-normal tissue payload delivery and limits systemic exposure. In vivo evaluation of EFTX-G12V-pTEAD in comparison to single agent EFTX-G12V in both xenograft and immunocompetent cancer models are planned to evaluate durability, efficacy and safety. Importantly, small molecule pTEAD inhibitors cause kidney toxicity including podocyte effacement, proteinuria and albuminuria, which has limited their clinical utility. Using spatial profiling in the kidney, we found that our siRNA molecules do not enter podocytes and largely clear through the proximal tubules, therefore we anticipate the potential for less kidney toxicity and a wider therapeutic window using this therapeutic modality. Together our findings represent a technological advance in multi-oncogene targeting using RNAi and a therapeutic modality capable of addressing resistance to KRAS inhibitors.", "source_company": "EnFuego Therapeutics Inc", "source_org_type": "公司", "row_number": 154, "target_meta": "KRAS G12V,TEAD", "MOA_meta": "其他"}, {"drug_name": "CAR T cell therapy", "company": "University of Pennsylvania", "org_type": "大学", "target": "未披露", "modality": "CAR", "importance_level": "中", "total_score": 71.5, "institution_score": 75, "track_score": 90, "milestone_score": 40, "field_heat_score": 85, "bonus_score": 0, "brief_reason": "CAR-T细胞疗法针对实体瘤的演进讨论，靶点未明确披露，modality为CAR属于细胞治疗热门赛道。机构为CAR-T领域顶尖学术中心但非商业公司得75分，赛道热度高得90分，但仅为会议报告无具体里程碑数据得40分，综合热度高，总分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/35", "id": "QtAKAJ0BN-zY606v4Xag", "source_drug_name": "CAR T cell therapy", "title": "Beyond blood: The evolution of CAR T therapy for solid malignancies", "abstract_text": "There is no abstract associated with this presentation.", "source_company": "University of Pennsylvania", "source_org_type": "大学", "row_number": 1, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "PLK1 degrader antibody conjugate (DAC)", "company": "Crossfire Oncology B.V.", "org_type": "公司", "target": "PLK1", "modality": "ADC", "importance_level": "中", "total_score": 71.5, "institution_score": 65, "track_score": 90, "milestone_score": 55, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "靶向PLK1的degrader ADC（DAC），通过新型激酶降解机制克服DXd/MMAE耐药ADC肿瘤。Crossfire为欧洲新兴biotech，ADC+蛋白降解赛道热门但仍处preclinical体内验证阶段，无临床里程碑。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5495", "id": "LFXM_5wBX1NQZOEH-LK6", "source_drug_name": "PLK1 degrader antibody conjugate (DAC)", "title": "In vivo characterization of a PLK1 degrader antibody conjugate for treatment of DXd and MMAE refractory tumors", "abstract_text": "Therapeutic applications for Antibody Drug Conjugates (ADCs) continue to expand, and it is expected that they will become a mainstay therapy in many cancer indications. Most ADCs in clinical development however utilize a limited selection of payloads. These are potent and efficacious but are also known to induce problematic off-tumor related toxicities. Moreover, this widespread use of a limited set of topoisomerase or tubulin binding payloads increasingly causes clinical resistance to entire classes of ADC-based therapies that are all based on the same payload. Expanding the limited payload arsenal with novel payloads is therefore urgently needed. Kinases play an essential role in the development and growth of many different cancers, and form an interesting target class for novel payloads. We have identified PLK1 kinase as a particular vulnerability in many types of cancer. High PLK1 expression often correlates with poor patient survival, and many cancer cells are highly sensitive to inhibition or knockout of PLK1. We generated a novel heterobifunctional PLK1 degrader with an average sub-nanomolar IC50 in a large in vitro cancer cell line proliferation panel. Our PLK1 degrader has all characteristics needed for a functional payload and because of its unique mechanism of action compared to classic ADC payloads, it can potently kill cancer cell lines that are resistant or refractory to classical payloads like DXd or MMAE. The PLK1 degrader payload is designed in such a way that it is rapidly removed from circulation once it diffuses out of the tumor into the vascular system. This reduces the risk of off-tumor related toxicity. PLK1 Degrader Antibody Conjugates (DACs) can be manufactured up to DAR8 without stability issues and have antibody-like pharmacokinetic properties. PLK1 DACs degrade all intracellular PLK1 within 48 hours and disrupt mitosis and the pre-replication complex, leading to severe DNA damage and apoptosis, which is consistent with the mechanism reported for PLK1 knockdown. The promise of our DAC technology was confirmed in vivo in a therapeutic triple negative breast cancer (MDA-MB-468) model where rapid tumor regression was achieved. Our PLK1 degrader-based DAC technology is broadly applicable and offers new treatment opportunities to cancer patients who are resistant or refractory to ADCs that carry classical payloads.", "source_company": "Crossfire Oncology B.V.", "source_org_type": "公司", "row_number": 27, "target_meta": "PLK1", "MOA_meta": "抗体偶联药物"}, {"drug_name": "(S)-ACE-OH", "company": "Tsinghua University", "org_type": "大学", "target": "TRIM21", "modality": "molecular glue", "importance_level": "中", "total_score": 71.5, "institution_score": 45, "track_score": 95, "milestone_score": 75, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "(S)-ACE-OH作为分子胶激活TRIM21 E3连接酶，选择性降解多聚体蛋白如NUP98/NPC组分，展示针对病理性多聚体蛋白的新型TPD平台。大学机构分数较低，但PROTAC+分子胶+多聚体选择性机制在热门TPD赛道有强创新，preclinical机制验证清晰。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11165", "id": "SlXM_5wBX1NQZOEH-LS6", "source_drug_name": "(S)-ACE-OH", "title": "Selective degradation of pathologic multimers via a novel TRIM21-engaging molecular glue and PROTAC platform", "abstract_text": "Background:​ Targeted protein degradation (TPD) holds great promise for cancer therapy, but its application is often constrained by the limited repertoire of E3 ligases and the challenge of selectively eliminating pathologic protein assemblies, such as those driving oncogenesis, while sparing monomeric forms. The E3 ligase TRIM21 is a compelling yet underexplored effector, as its activation is hypothesized to require substrate multimerization, potentially conferring intrinsic selectivity for diseased-associated protein complexes.\nMethods and Results:​ We report a novel TPD strategy centered on the activation of TRIM21. Initially, we discovered that (S)-ACE-OH, a metabolite of acepromazine, functions as a molecular glue by inducing a productive interaction between TRIM21 and the multimeric Nuclear Pore Complex (NPC) component NUP98. To systematically map the specificity and scope of this degradation event, we employed quantitative and TurboID proteomics.​ This analysis confirmed the potent and selective degradation of multiple NPC proteins, consistent with the disruption of a large multiprotein complex. Crucially, monomeric proteins remained unaffected, validating the hypothesized multimer-selectivity of TRIM21-based degradation. This selectivity was further demonstrated by engineering acepromazine-based PROTACs, which effectively degraded diverse multimeric client proteins, including components of biomolecular condensates.\nConclusion:​ Our work establishes TRIM21 as a promising new E3 ligase for TPD, capable of selectively targeting multimeric proteins and pathologic assemblies. The proteomic analyses were pivotal in unequivocally defining this unique selectivity profile,​ providing a robust experimental foundation for this platform. This TRIM21-based degradation strategy opens a new therapeutic avenue for directly targeting undruggable, multimeric oncoproteins, with broad implications for cancer treatment.", "source_company": "Tsinghua University", "source_org_type": "大学", "row_number": 252, "target_meta": "TRIM21", "MOA_meta": "分子胶"}, {"drug_name": "a novel DR5-targeting ADC", "company": "Bliss Biopharmaceutical Co., Ltd.", "org_type": "公司", "target": "DR5", "modality": "ADC", "importance_level": "中", "total_score": 71.5, "institution_score": 65, "track_score": 80, "milestone_score": 70, "field_heat_score": 75, "bonus_score": 3, "brief_reason": "药物为靶向DR5的ADC，通过三价抗体设计结合Top-1抑制剂实现双重作用机制，展现优于对照抗体INBRX109的抗瘤活性、更宽治疗窗和更好安全性，支持进入临床。机构为国内专注ADC的临床阶段biotech，融资活跃并有国际合作，ADC+热门凋亡靶点赛道热度高，前临床数据强劲但尚未临床。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9649", "id": "RlXM_5wBX1NQZOEH-LG5", "source_drug_name": "a novel DR5-targeting ADC", "title": "A DR5-targeting ADC exhibits superior anti-tumor activity and potentially better therapeutic window", "abstract_text": "Targeting death receptor DR5 with agonist antibody could trigger extrinsic apoptosis via caspase activation in cancer cells while sparing normal tissues. Ozekibart (INBRX109), a tetra-valent anti-DR5 antibody, showed significant efficacy as a monotherapy in patients with advanced or metastatic, unresectable chondrosarcoma, with disease control rate (DCR) of 54%, (compared to 27.5% in the placebo group). Later in a study of advanced Ewing sarcoma, Ozekibart combined with irinotecan and temozolomide demonstrated improved clinical benefit with an ORR of 64% and a DCR of 92%. Encouraged with these results, we designed a DR5-targeting ADC with the aim to synergize the extrinsic apoptosis activity of DR5 engaging and superb cytotoxicity effect of Top-1 inhibitor. In this presentation we show systematic evaluation of this novel ADC including specific tumor cell engaging, anti-tumor efficacy, serum stability, and pharmacokinetics (PK) in target-humanized mice. First, the unique design of the tri-valent DR5-targeting antibody demonstrated superior activity over counterparts. Second,its resulting ADC form showed a robust tumor growth inhibition across diverse xenografts, potentially benefit from its dual mode of action design, surpassing clinically advanced control agents (INBRX109). Our ADC showed dose dependent in vivo antitumor activity without hook effect seen with agonist antibodies. Finally, this ADC showed better in vivo safety profile: lower on-target off-tumor apoptosis, longer half-life and better tolerability in comparison with that of INBRX109,suggesting a potentially wider therapeutic window. These results may support progression of this novel DR5-tageting ADC into clinical development as a potentially more potent and safer DR5-targeted therapy.", "source_company": "Bliss Biopharmaceutical Co., Ltd.", "source_org_type": "公司", "row_number": 358, "target_meta": "DR5", "MOA_meta": "抗体偶联药物"}, {"drug_name": "anti-GPC3 antibody-drug conjugate", "company": "Baylink Biosciences", "org_type": "公司", "target": "GPC3", "modality": "ADC", "importance_level": "中", "total_score": 71.5, "institution_score": 65, "track_score": 90, "milestone_score": 55, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "靶向GPC3的下一代ADC，采用新型蛋白降解剂payload并支持dual-payload设计，针对HCC和NSCLC显示优异preclinical疗效。Baylink作为专注创新ADC的biotech公司处于发展阶段，赛道ADC+热门靶点GPC3热度高，但仍preclinical缺乏临床里程碑。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5489", "id": "elXM_5wBX1NQZOEH-LS6", "source_drug_name": "anti-GPC3 antibody-drug conjugate", "title": "Novel GPC3-targeting antibody-drug conjugate using novel payload or dual payloads to treat hepatocellular carcinoma and non-small-cell lung cancer", "abstract_text": "Glypican-3 (GPC3) is a highly promising therapeutic target due to its selective, abundant overexpression in hepatocellular carcinoma (HCC) and certain subsets of non-small cell lung cancer (NSCLC), while being largely absent in normal adult tissues. A Phase 1 trial with a GPC3-targeted CAR-T therapy showed an objective response rate of 57 percent in heavily pre-treated patients with advanced HCC, highlighting the potential of GPC3 as a viable tumor-specific antigen for targeted therapy. ADC modality offers distinct advantages over CAR-T therapies, including off-the-shelf availability, lack of risk of cytokine release syndrome, and significant accessibility and cost advantages. However, HCC is known to be resistant to traditional chemotherapy thus traditional ADC payloads likely won’t work. We have developed a series of next-generation anti-GPC3 antibody-drug conjugates that combine our proprietary GPC3-targeting antibody and distinct payload classes including topoisomerase inhibitor and a novel protein degrader. Compared to benchmark GPC3-targeting antibodies, our antibody binds a unique epitope on GPC3, resulting in enhanced internalization and significantly improved ADC-mediated cytotoxicity in GPC3-positive cells. Our novel protein degrader payload showed broad anti-proliferative activity in vitro, including potent cytotoxicity in DXd-resistant cell lines and HCC cell lines. In vivo, our GPC3 single-payload or dual-payload ADC molecules showed robust anti-tumor efficacy in multiple HCC and NSCLC CDX and PDX models. We believe that our anti-GPC3 ADC can be an effective off-the-shelf biologic therapy for HCC and NSCLC patients.", "source_company": "Baylink Biosciences", "source_org_type": "公司", "row_number": 917, "target_meta": "GPC3", "MOA_meta": "抗体偶联药物"}, {"drug_name": "Coltac's molecular glue", "company": "Coltac Therapeutics", "org_type": "公司", "target": "β-Catenin", "modality": "molecular glue", "importance_level": "中", "total_score": 71.5, "institution_score": 65, "track_score": 90, "milestone_score": 50, "field_heat_score": 85, "bonus_score": 3, "brief_reason": "分子胶机制促进β-Catenin的蛋白酶体降解，针对Wnt通路驱动的结直肠癌等肿瘤，提供难成药靶点新策略。Coltac为新兴以色列biotech，平台创新但仍处早期发现阶段，热门TPD+分子胶+高未满足需求靶点带来较高潜力。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3870", "id": "RJ7M_5wBZznHJdnt_W7O", "source_drug_name": "Coltac's molecular glue", "title": "Targeting Beta-catenin in colorectal cancer: Novel molecular glue drug candidates by Coltac's BOND+ platform", "abstract_text": "β-Catenin is a central oncogenic driver through its regulation of the Wnt signaling pathway, controlling cell proliferation, metastasis, drug resistance, across multiple cancer types. Its critical role is well-established in colorectal cancer (CRC), hepatocellular carcinoma, endometrial cancer, desmoid tumors, and subsets of ovarian cancer. In over 90% of colorectal cancers, Wnt/β-catenin pathway mutations elevate β-catenin levels, promoting tumorigenesis and poor prognosis. Restoring control of aberrant Wnt signaling in β-catenin–driven cancers hold significant potential to suppress tumor growth and improve clinical outcomes. Targeted protein degradation (TPD) by molecular glues offers a promising therapeutic strategy for modulating oncogenic drivers such as β-catenin proteins, historically considered challenging for conventional small-molecule inhibition. Discovery of selective glues remains limited by low throughput screening methods, weak detection sensitivity, and the complexity of E3-substrate biology. Coltac Therapeutics developed BOND+ a proprietary bacterial ubiquitin-dependent positive-selection screening system designed to identify molecular glues that enhance E3 ligase-target engagement. This synthetic platform converts functional ubiquitination events into bacterial growth, by leveraging the bacterial environment, which lacks deubiquitinases, proteasomal and lysosomal degradation systems, redundant E3 ligases, and any ubiquitylation-dependent degradation machinery, thus enabling direct, low-signal to noise readouts of functional target engagement. Identified hits are further validated in mammalian cell assays, followed by mechanistic studies and continuous optimization through medicinal chemistry and in silico refinement. Using BOND+ platform we identified selective molecular glue candidates that promote proteasome-dependent degradation of β-catenin and modulate downstream associated signaling. Lead compounds demonstrated up to 100-fold inhibition potency relative to initial hits, with preferential anti-tumor activity effects in various CRC Wnt-dependent cancer cell models. Early mechanistic studies confirmed target selectivity and E3-ligase dependence. Structure activity relationship (SAR) optimization and in vivo pharmacology studies refined potency and translational potential. Despite β-catenin central role in CRC there are no approved therapies directly target β-catenin, highlighting a significant unmet need. Coltac’s BOND+ platform enabled rapid discovery and validation supporting therapeutic drugs for β-catenin. We demonstrated potent antitumor activity highlighting Coltac’s molecular glue as a new drug candidate in β-catenin-driven cancers.", "source_company": "Coltac Therapeutics", "source_org_type": "公司", "row_number": 1172, "target_meta": "β-cat", "MOA_meta": "分子胶"}, {"drug_name": "a novel hit compound", "company": "Baylor College of Medicine", "org_type": "大学", "target": "AR/AR-V7", "modality": "molecular glue degrader", "importance_level": "中", "total_score": 71.5, "institution_score": 35, "track_score": 95, "milestone_score": 85, "field_heat_score": 90, "bonus_score": 8, "brief_reason": "靶向AR全长及耐药变体AR-V7的分子胶降解剂，直接结合不可成药的NTD结构域，实现双重降解克服恩杂鲁胺耐药，机制新颖且选择性高。机构为大学学术型，得分较低，但热门分子胶+前列腺癌耐药未满足需求+强preclinical数据（优于临床AR-PROTAC、肿瘤显著抑制、无明显毒性）带来高赛道与里程碑分。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/2047", "id": "VZ7M_5wBZznHJdnt_W7P", "source_drug_name": "a novel hit compound", "title": "First-in-class dual AR/AR-V7 molecular glue degraders targeting the undruggable N-terminal domain to overcome therapeutic resistance in prostate cancer", "abstract_text": "Metastatic castration-resistant prostate cancer (mCRPC) remains a uniformly lethal malignancy, driven by persistent dependence on the androgen receptor (AR) signaling pathway. Over 90% of prostate cancer (PC) therapies target the AR ligand-binding domain (LBD). However, the selective pressure imposed by these agents inevitably promotes therapeutic resistance and disease progression, ultimately driving mortality. Expression of AR splice variants, most notably AR-V7, that lack the LBD yet remain constitutively active, is a key mechanism of treatment resistance. Clinically, AR-V7 expression is strongly associated with resistance to all AR pathway inhibitors (ARPIs), including enzalutamide and abiraterone. Alarmingly, AR-V7 is detected in >75% of men with mCRPC, yet there are no approved inhibitors—underscoring a profound unmet clinical need. Thus, directly targeting AR-V7 represents one of the most urgent and unsolved challenges in prostate cancer drug development, with clear implications for survival and quality of life. To address this challenge, we conducted a high-throughput phenotypic screen of 170,000 small molecules and identified a novel hit compound—the first-in-class dual degrader of AR-V7 and full-length AR, defined by a previously unreported chemotype. Medicinal chemistry/SAR optimization yielded potent lead compounds (IC50 <10 nM) with improved selectivity and favorable drug-like properties. This systematic optimization effort combined iterative analog synthesis, structure-activity analysis, and physicochemical profiling to deliver nanomolar potency alongside favorable solubility and stability profiles, enabling downstream in vivo evaluation. In vivo, pharmacokinetic (PK)-optimized compounds significantly suppressed tumor growth in the enzalutamide-resistant 22Rv1 xenograft model, reversed resistance, and outperformed ARV-110, the only full-length AR-PROTAC degrader in clinical trials, by >10-fold in efficacy, with no effect on mouse body weight—establishing both robust antitumor activity and excellent tolerability. Pharmacodynamic (PD) studies revealed near-complete degradation of AR/AR-V7 proteins within 24 hours of final dose, tightly correlating with rapid tumor growth inhibition. Importantly, toxicity studies across multiple dosing regimens showed no histopathological abnormalities in major organs, further supporting the translational potential of this new therapeutic class. Mechanistic studies confirmed rapid degradation of AR-V7/AR via the ubiquitin-proteasome pathway, dependent on Cullin-RING E3 ligase activity. A CRISPR-based E3 ligase screen implicated the DDB1-RBX1-Cullin-RING complex as the mediator of degradation, consistent with a molecular glue mechanism. This represents one of the first demonstrations of a molecular glue-mediated engagement of this E3 ligase complex in prostate cancer, further underscoring the novelty of our approach. Global proteomics demonstrated deep proteome coverage of the entire proteome of ~10,000 proteins and exceptional selectivity: AR/AR-V7 ranked among the top 1% of significantly downregulated proteins, while sparing all other major human nuclear receptors, including ER, PR, and GR, and avoiding liabilities of prior PROTAC-based AR degraders—highlighting strong specificity and favorable translational potential for clinical development. Using cellular thermal shift assays, AR truncation mutants, and Cryo-EM studies, we demonstrated direct binding of our lead compounds to the intrinsically disordered N-terminal domain (NTD), shared by both AR and AR-V7. We further mapped the binding site to the TAU1/AF-1 subdomain— the first demonstration of small-molecule engagement of this notoriously “undruggable” region. This provides long-sought proof-of-concept that the unstructured AR-NTD, which has defied decades of drug targeting efforts, can indeed be targeted with small molecules. Our findings therefore expand the druggable proteome to include intrinsically disordered regions, with broad implications beyond prostate cancer. Importantly, our lead compounds were able to overcome enzalutamide resistance and inhibit all clinically validated ARPIs-resistant isoforms, including LBD-domain mutations. These results suggest that our compounds deliver not only a solution for AR-V7-mediated resistance but also a generalized “resistance-proof” strategy by simultaneously targeting multiple clinically relevant AR variants. Taken together, these data establish our lead compounds as first-in-class dual AR-V7/AR molecular glue degraders with a novel NTD-targeted mechanism and strong preclinical activity. To advance toward clinical translation, the next phase of our research will systematically define the structural basis of compound-NTD interaction, evaluate drug metabolism and safety in higher-order animal models, and explore rational combination strategies with standard-of-care agents. The objective here is to define the precise molecular mechanism of action and assess therapeutic potential in clinically relevant models. Collectively, these findings support a paradigm-shifting therapeutic strategy for targeting previously “undruggable” drivers like AR-V7. Unlike all existing AR-directed therapies that target the LBD, this approach simultaneously degrades AR and AR-V7 in a single treatment, directly addressing the central clinical challenge of therapeutic resistance. Moreover, by establishing proof-of-concept for disordered protein domain-targeted glue degraders, this work opens a broadly applicable platform to drug other transcription factors and intrinsically disordered proteins implicated across multiple cancers and diseases. By enabling dual degradation of AR (the initiating oncogenic driver in PC) and AR-V7 (the lethal, treatment-resistant variant), our drug candidate has the potential to transform the treatment landscape—benefiting patients with both hormone-sensitive and advanced castration-resistant disease, while delaying or preventing AR-V7-mediated progression. Ultimately, this work charts a new course for prostate cancer therapy by providing a first-in-class approach capable of addressing the major cause of therapeutic failure, with the potential to meaningfully extend survival and improve quality of life.", "source_company": "Baylor College of Medicine", "source_org_type": "大学", "row_number": 1183, "target_meta": "AR-v7", "MOA_meta": "降解剂"}, {"drug_name": "MPSA-AB5000", "company": "Kyinno Biotechnology Co., LTD", "org_type": "公司", "target": "未披露", "modality": "other", "importance_level": "中", "total_score": 71, "institution_score": 65, "track_score": 80, "milestone_score": 70, "field_heat_score": 75, "bonus_score": 3, "brief_reason": "MPSA-AB5000为高通量细胞膜蛋白筛选阵列平台，用于抗体靶点识别和脱靶评估，非药物本身而是工具平台；机构为国内创新型biotech CRO，赛道属抗体开发关键支持技术热度较高，preclinical阶段技术亮点明显。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5475", "id": "AVXM_5wBX1NQZOEH-LS6", "source_drug_name": "MPSA-AB5000", "title": "MPSA-AB5000: A high-throughput cell-based membrane protein screening array for accurate early-stage off-target assessment to accelerate safer antibody therapeutic development", "abstract_text": "Antibody drug development is a lengthy and complex process, often hindered by off-target binding that affects approximately 25-30% of preclinical candidates. With the growing importance of advanced modalities such as CD3 bispecific antibodies, antibody-drug conjugates (ADCs), and CAR-T therapies, early and accurate off-target assessment has become essential. However, conventional assays—including immunohistochemistry (IHC), ELISA, and flow cytometry (FACS)—remain limited in sensitivity, specificity, and throughput.To address these limitations, we developed the Membrane Protein Screening Array (MPSA-AB5000), a high-throughput, cell-based platform for comprehensive identification of antibody targets and off-targets. The MPSA-AB5000 expresses a broad spectrum of human membrane proteins in live cells, maintaining native conformation and post-translational modifications to ensure physiologically relevant binding analysis. MPSA-AB5000 is a high-throughput, cell-based platform for identifying antibody targets and off-targets, enhancing antibody specificity screening and reducing development risks. To provide the highest level of sensitivity, MPSA-AB5000 uses luciferase reporter cell line detection. The wash-free strategy reduces false negatives, and signal amplification makes remarkable discrimination. Furthermore, the platform integrates a Protein A-based reporter system, leveraging Protein A’s strong Fc-binding affinity—particularly for human IgG1, IgG2, and IgG4—to immobilize antibodies on reporter cells. This allows detection of off-target-induced signaling even in Fc-modified formats such as IgG1-LALA or IgG4. Collectively, the MPSA-AB5000 provides a robust, versatile, and physiologically relevant solution for antibody target deconvolution and specificity evaluation, accelerating the discovery and optimization of safer antibody therapeutics.", "source_company": "Kyinno Biotechnology Co., LTD", "source_org_type": "公司", "row_number": 67, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "KIR-CAR", "company": "Abramson Cancer Center, University of Pennsylvania", "org_type": "医院", "target": "mesothelin", "modality": "CAR", "importance_level": "中", "total_score": 71, "institution_score": 65, "track_score": 85, "milestone_score": 60, "field_heat_score": 75, "bonus_score": 3, "brief_reason": "KIR-CAR为针对mesothelin的创新型KIR-based CAR-T细胞疗法，属于细胞治疗热门赛道且针对实体瘤高表达靶点。机构为顶尖学术医院而非头部药企，处于首个人体剂量递增研究阶段（FIH），preclinical基础强但临床数据初现，故综合重要性中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11991", "id": "HlXM_5wBX1NQZOEH-LG5", "source_drug_name": "KIR-CAR", "title": "Initial results of a first in human dose-escalation study of KIR-CAR in patients with advanced mesothelin-expressing solid tumors", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Abramson Cancer Center, University of Pennsylvania", "source_org_type": "医院", "row_number": 175, "target_meta": "MSLN", "MOA_meta": "其他"}, {"drug_name": "uPAR-targeted CAR-NK platform", "company": "The University of Texas MD Anderson Cancer Center", "org_type": "医院", "target": "uPAR", "modality": "CAR-NK", "importance_level": "中", "total_score": 71, "institution_score": 60, "track_score": 85, "milestone_score": 70, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "靶向uPAR的CAR-NK细胞针对AML显示出特异性强、持久的体外和体内抗肿瘤活性，并通过IL-15装甲增强持久性；MD Anderson作为顶级癌症中心在CAR-NK领域有领先研究，但仍为学术机构preclinical阶段，热门细胞治疗赛道但uPAR靶点非最热。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9404", "id": "A1XM_5wBX1NQZOEH-LO6", "source_drug_name": "uPAR-targeted CAR-NK platform", "title": "uPAR-targeting CAR-NK cells enhance cytotoxicity against acute myeloid leukemia", "abstract_text": "Background: Relapsed/refractory acute myeloid leukemia (AML) remains difficult to treat, highlighting the need for new therapies. NK cell-based immunotherapy offers potent antitumor activity with low risk of GVHD or severe CRS. The urokinase plasminogen activator receptor (uPAR), encoded by PLAUR, is highly expressed on malignant and senescent cells while largely absent from healthy HSCs and most normal vital organs. We found PLAUR significantly upregulated in AML and confirmed strong uPAR surface expression on primary blasts. Based on this favorable profile, we developed an off-the-shelf uPAR-targeted CAR-NK platform with a CD28 costimulatory domain and secreted IL-15 to enhance persistence.\nMethods: Cord blood-derived NK cells were preactivated with IL-12/15/18 and transduced to express (i) uPAR-CAR, (ii) IL-15, or (iii) uPAR-CAR/IL-15. CAR expression, cytokine production, and phenotype were assessed by flow cytometry, ELISA, and CyTOF, respectively. Antileukemic activity against AML cell lines (MV4-11, THP-1, OCI-AML3) and primary blasts was tested by IncuCyte real-time killing and Annexin V staining. Long-term activity was assessed by sequential tumor rechallenge. In vivo efficacy was evaluated in NSG mice engrafted with luciferase-labeled OCI-AML3 and treated with a single NK infusion.\nResults: uPAR was highly expressed on AML blasts but minimal on healthy HSCs/HSPCs, confirming its suitability as a CAR-NK target. uPAR-CAR/IL-15 NK cells were efficiently generated, secreted IL-15, and expanded robustly. In vitro, they showed markedly enhanced and antigen-specific killing of all uPAR+ AML lines and primary blasts compared with CAR-only, IL-15-only, or non-transduced NK cells (p < 0.0001), while PLAUR-knockout cells resisted killing. uPAR-CAR/IL-15 NK cells produced more IFN-γ and TNF-α and maintained superior function during repeated tumor exposure, with CyTOF revealing an activation/cytotoxicity-enriched metacluster. In vivo, a single uPAR-CAR/IL-15 NK infusion significantly reduced leukemia burden, delayed progression, and improved NK persistence in bone marrow. Compared with non-transduced NKs, tumor burden in peripheral blood (p < 0.05), bone marrow (p = 0.001), and spleen (p < 0.01) was substantially reduced, with no observed toxicity or weight loss. Taken together, uPAR is a safe, selective AML target. uPAR-CAR NK cells, particularly when armored with IL-15, display potent, antigen-specific, and durable antileukemic activity, supporting advancement of this platform for AML therapy.", "source_company": "The University of Texas MD Anderson Cancer Center", "source_org_type": "医院", "row_number": 656, "target_meta": "PLAUR", "MOA_meta": "CAR NK细胞疗法"}, {"drug_name": "MAIT engagers", "company": "Biomunex Pharmaceuticals", "org_type": "公司", "target": "未披露", "modality": "bispecific antibody", "importance_level": "中", "total_score": 71, "institution_score": 65, "track_score": 85, "milestone_score": 60, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "MAIT engagers通过特异性结合MAIT细胞的invariant TCR并连接肿瘤抗原，激活MAIT介导的肿瘤细胞杀伤，避免Treg抑制和CRS风险，机制新颖优于传统CD3 engagers。机构为专注创新双抗的中小型欧洲biotech，得分中等；赛道为热门T细胞重定向双抗+固瘤突破潜力高；仍处preclinical阶段但有体外/体内活性及安全性优势。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5102", "id": "vFXM_5wBX1NQZOEH-LS6", "source_drug_name": "MAIT engagers", "title": "MAIT engagers: Avoiding Treg suppression to deliver stronger activity in solid tumors.", "abstract_text": "MAIT engagers are part of the immune cell engager drug modality and specifically target Mucosal Associated Invariant T cells (MAITs) via their unique T cell receptor (TCR) and tether them to cancer cells, via a tumor antigen, to elicit MAIT-mediated cell death. MAIT cells are an abundant cytotoxic subset of non-conventional T cells that are present in blood and all major organs and are particularly enriched in barrier tissues. Classical CD3 engagers activate all T cell subsets, including the regulatory T-cell (T-regs) population whose activation in the tumor microenvironment (TME) will dampen the intended cytotoxicity of the CD8 cytotoxic T cells and will limit CD3 engager efficacy. Unlike CD3 engagers, MAIT engagers only activate MAIT cells and do not cause increased immune suppression via T-reg activation or cytokine release syndrome (CRS) via general CD4 T cell activation. MAIT engagers were generated using Biomunex’s proprietary bispecific, tetravalent antibody platform, BiXAb. MAIT-cell activation, proliferation, degranulation and cytotoxicity assays were established in co-culture between tumor cells, immune cell subsets (CD8 or PBMCs) and BiXAb MAIT engagers. Analysis of activation, degranulation and proliferation was followed by FACs whilst cytotoxicity was assessed by chromium release. Regulatory T cells were enriched from PBMCs and used in co-culture assays to assess CD8 T cell repression as judged by IL-2 release. General cytokine release was measured by Legend Plex or ELISA. Cytotoxicity of tumor-resident MAITs, from fresh patient samples, was determined by impedance measurements. In vivo efficacy studies were performed in humanized mouse models by co-injection of CD8s, cancer cells and the MAIT engager. MAIT engagers are as potent as classical CD3 engagers in terms of activation, degranulation, proliferation and cytotoxicity towards cancer cells. However, in co-culture assays of cancer cells and PBMCs, CD3 engagers induce large quantities of cytokines, especially IL-6 which is known to initiate CRS whilst MAIT engagers induced similar levels to control antibodies suggesting greater safety. CD3 engagers induced Treg activation proliferation and release of IL-10 in a dose dependent manner and induced Treg suppression of CD8 activation. MAIT engagers had no impact on Treg biology and increased immune suppression. Ex vivo cytotoxicity of tumor-resident MAIT cells using dissociated Ovarian cancer samples at “real E:T ratios” showed that MAITs in human tumors can respond to MAIT engagers, proliferate and eliminate tumor cells. In vivo efficacy studies showed that MAIT engagers can control human tumors in mice models of cancer. MAIT engagers are as potent as CD3 engagers but have a significantly improved safety profile. More importantly, they do not cause Treg activation which can dampen T-cell cytotoxicity in the TME and are expected to show greater efficacy in the clinic for the treatment of solid tumors.", "source_company": "Biomunex Pharmaceuticals", "source_org_type": "公司", "row_number": 971, "target_meta": "not available", "MOA_meta": "双特异性抗体"}, {"drug_name": "CDH17xCD3 bispecific T-cell engager", "company": "NeoMab Biotechnology Co,. Ltd", "org_type": "公司", "target": "CDH17", "modality": "bispecific antibody", "importance_level": "中", "total_score": 71, "institution_score": 65, "track_score": 85, "milestone_score": 60, "field_heat_score": 75, "bonus_score": 2, "brief_reason": "靶向CDH17的CDH17xCD3双特异性T细胞衔接器，机制为T细胞重定向杀伤胃肠道肿瘤高表达CDH17的实体瘤细胞。NeoMab为国内新兴biotech子公司（GemPharmatech旗下），专注抗体发现平台，非头部药企故机构分中等；TCE+CDH17在实体瘤热门但非顶级靶点，preclinical数据较扎实包括体外特异杀伤和体内肿瘤消退，综合热度较高，总分中位。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5757", "id": "kp7M_5wBZznHJdnt_W3O", "source_drug_name": "CDH17xCD3 bispecific T-cell engager", "title": "Novel T cell engager targeting CD3 and CDH17 for the treatment of solid tumors", "abstract_text": "Background: Despite the success of T-cell engagers (TCEs) in hematologic cancers, their translation to solid tumors has been limited by key obstacles such as the immunosuppressive tumor microenvironment, inefficient T-cell trafficking, and antigen heterogeneity. The pursuit of suitable target antigens is therefore critical. Cadherin-17 (CDH17), which is highly expressed in many gastrointestinal malignancies but shows limited normal tissue expression, offers a compelling opportunity for next-generation TCE therapy.\nMethods: A novel, bispecific T-cell engager (TCE) was engineered for concurrent binding to CD3 and cadherin-17 (CDH17). Its cytotoxic potency was quantified against a panel of CDH17-positive human cancer cell lines in co-culture assays with healthy donor peripheral blood mononuclear cells (PBMCs). T-cell activation (CD69+/CD25+ upregulation) and cytokine secretion were profiled by flow cytometry and immunoassay, respectively. In vivo antitumor efficacy was evaluated in immunodeficient mice bearing CDH17-positive gastric cancer cell-derived xenografts (CDX).\nResults: The CDH17xCD3 T cell engager exhibited high-affinity binding to CDH17, coupled with a modulated affinity for CD3. In vitro, the molecule induced potent and specific lysis of CDH17-positive tumor cells in a dose-dependent manner, while sparing CDH17-negative controls. This targeted cytotoxicity was accompanied by a reduced cytokine release profile compared to a conventional CD3-engaging benchmark, In vivo, our TCE treatment led to enhanced tumor growth inhibition and marked regression in CDH17-high CDX models, with no significant systemic toxicity observed at efficacious doses.\nConclusion: The novel CDH17xCD3 bispecific T-cell engager exhibits potent and targeted anti-tumor activity, supporting its translational potential as an immunotherapeutic agent for CDH17-positive solid tumors. The favorable efficacy and safety profile observed warrants further clinical investigation.", "source_company": "NeoMab Biotechnology Co,. Ltd", "source_org_type": "公司", "row_number": 1048, "target_meta": "CDH17", "MOA_meta": "双特异性抗体"}, {"drug_name": "MET/HER3 bispecific ADC", "company": "OBI Pharma, Inc", "org_type": "公司", "target": "c-MET 和 HER3", "modality": "bispecific ADC", "importance_level": "中", "total_score": 71, "institution_score": 65, "track_score": 90, "milestone_score": 50, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "药物为靶向c-MET和HER3的双特异性ADC，采用双payload设计以克服耐药并增强抗肿瘤活性，机制创新且针对异质性肿瘤。OBI Pharma为台湾中型biotech公司，非全球头部，赛道热门但仍处preclinical阶段，综合潜力中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4051", "id": "Zp7M_5wBZznHJdnt_W7P", "source_drug_name": "MET/HER3 bispecific ADC", "title": "The MET/HER3 antibody-drug conjugate with dual payload: A dual-target approach to eliminate tumor escape mechanism", "abstract_text": "Clinical evidence supports combination approaches such as EGFR plus MET TKIs, which achieve responses in MET-amplified resistance settings and demonstrate the critical role of MET signaling in acquired resistance. Meanwhile, HER3-directed ADCs have shown meaningful activity in refractory tumors, underscoring the therapeutic relevance of HER3 in resistant and heterogeneous cancer populations. Together, these findings highlight the rationale for co-targeting cMET and HER3, as simultaneous inhibition of these complementary pathways provides a strong foundation for the development of a bispecific ADC (BsADC) to overcome resistance and enhance antitumor efficacy. Our MET/HER3 bispecific ADC was constructed using the proprietary glycan-based site specific platform to simultaneously engage c-MET and HER3. The ADC carries two complementary cytotoxins— a microtubule inhibitor, MMAE and a topoisomerase I inhibitor derivative, exatecan, conjugated through the stable linker for controlled intracellular release and maximize antitumor activity. Blue native PAGE (BN-PAGE) and proximity ligation assay (PLA) data confirmed that simultaneous MET and HER3 engagement promote receptor clustering, enhancing internalization and intracellular payload delivery. In preclinical models, the bispecific dual-payload ADC induced stronger tumor regression than monospecific or parental ADCs. Broad activity was observed in c-MET/HER3 dual-positive non-small cell lung cancer and colorectal cancer models. This glycan-based site specific MET/HER3 bispecific dual-payload ADC warrants further clinical investigation as a promising therapeutic option for refractory tumors co-expressing cMET and HER3.", "source_company": "OBI Pharma, Inc", "source_org_type": "公司", "row_number": 1191, "target_meta": "c-Met,HER3", "MOA_meta": "抗体偶联药物"}, {"drug_name": "EGFR/MET bispecific ADC", "company": "Promatix Biosciences Ltd.", "org_type": "公司", "target": "EGFR/MET", "modality": "bispecific ADC", "importance_level": "中", "total_score": 70.5, "institution_score": 65, "track_score": 90, "milestone_score": 50, "field_heat_score": 85, "bonus_score": 3, "brief_reason": "EGFR/MET双特异性ADC利用AND逻辑实现肿瘤选择性共表达靶向，属于热门的双抗ADC赛道且靶点组合具创新性。Promatix为新兴biotech，preclinical阶段展示功能验证和新型组合潜力，得分受机构早期阶段和preclinical限制。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5518", "id": "GVXM_5wBX1NQZOEH-LO6", "source_drug_name": "EGFR/MET bispecific ADC", "title": "Overcoming the limited monospecific target landscape in cancer via discovery of tumor selective AND and OR gate bispecifics", "abstract_text": "The pool of membrane proteins suitable for monospecific antibody-drug conjugates (ADCs) is inherently limited, restricting tumor selectivity and leaving many cancers without actionable antigens. Bispecific ADCs unlock a much larger combinatorial target universe by pairing antigens, enabling AND-gate designs that enforce dual expression for engagement and OR-gate designs that extend coverage where individual markers are insufficient. However, rational construction of such bispecifics depends on identifying antigen pairs that are co-expressed in tumors but absent - or expressed only individually - in normal tissues. To meet this need, we developed a discovery framework that combines quantitative proteomic profiling across more than 14 tumor types, matched normal tissues, and cell lines with computational modeling of cancer-normal specificity. This approach systematically evaluates both AND- and OR-logic potential across all bispecific ADC pairings currently under clinical or preclinical investigation, while also uncovering previously unexplored combinations with favorable selectivity profiles. Our analysis confirms that the universe of high-selectivity monospecific targets is extremely small, whereas the application of AND-logic markedly expands the number of viable tumor-restricted pairings by exploiting cancer-specific co-expression signatures. OR-logic designs provide complementary value by maintaining or improving selectivity while accommodating tumor expression heterogeneity. Among existing clinical bispecific ADC programs, only a limited subset demonstrates true AND-gate behavior, with the EGFR/MET pairing showing the most robust tumor-restricted co-expression profile. Beyond the current landscape, the platform identifies novel AND-gate opportunities with predicted improvements in therapeutic index. Functional evaluation of one such candidate validated the model’s prediction of avidity-driven dual engagement and tumor-selective cytotoxicity. Collectively, these findings demonstrate that a proteomics-driven AND/OR bispecific discovery platform can substantially expand the therapeutic target space beyond what is achievable with monospecific ADCs, enabling the development of safer and more selective next-generation cancer therapeutics.", "source_company": "Promatix Biosciences Ltd.", "source_org_type": "公司", "row_number": 51, "target_meta": "EGFR,c-Met", "MOA_meta": "抗体偶联药物"}, {"drug_name": "DXA038-CPT113", "company": "Hangzhou DAC Biotechnology Co., Ltd", "org_type": "公司", "target": "GP220/350 和 EGFR", "modality": "ADC", "importance_level": "中", "total_score": 70.5, "institution_score": 65, "track_score": 90, "milestone_score": 50, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "该双特异性ADC同时靶向EBV GP220/350和EGFR，用于EBV阳性鼻咽癌精准治疗，具有双靶点提升选择性和内化效率的机制优势。机构为专注ADC的国内创新型biotech公司，赛道热门但仍处早期研究阶段，整体潜力中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6471", "id": "Bp7M_5wBZznHJdnt_W7O", "source_drug_name": "DXA038-CPT113", "title": "A novel 2+2 IgG-like bispecific antibody-drug conjugate targeting EBV GP220/350 and EGFR for selective treatment of nasopharyngeal carcinoma", "abstract_text": "Nasopharyngeal carcinoma (NPC) is endemic in East and Southeast Asia, with Epstein-Barr virus (EBV) infection as a primary etiological factor. The EBV envelope glycoprotein GP220/350 is highly expressed on EBV-positive NPC cells, serving as a tumor-specific antigen. Epidermal growth factor receptor (EGFR) is also overexpressed in >80% of NPC cases and is a validated therapeutic target (e.g., cetuximab). Bispecific antibodies (bsAbs) offer unique advantages by co-targeting two antigens, enhancing tumor selectivity and internalization efficiency. Here, we report the development of a 2+2 IgG-like bispecific antibody-drug conjugate (ADC) co-targeting GP220/350 and EGFR for precise NPC therapy. The bsAb was engineered as a 2+2 IgG-like molecule. The GP220/350-binding arm was derived from a fully humanized synthetic VHH (single-domain antibody) library and a high affinity binder C2 was selected via phage display. The EGFR-binding arm was based on nimotuzumab, a low-affinity EGFR antibody chosen to minimize on-target/off-tumor toxicity. The bsAb designated as DXA038 was conjugated to a topoisomerase I inhibitor payload CPT113 via a cleavable linker, with an average drug-to-antibody ratio (DAR) of 4. Binding affinity, in vitro cytotoxicity and in vivo efficacy were assessed. DXA038-CPT113 showed superior activity both in vitro and in vivo compared to nimotuzumab-CPT113.This bispecific ADC represents a promising therapeutic strategy for EBV-positive NPC, addressing unmet needs in precision oncology.", "source_company": "Hangzhou DAC Biotechnology Co., Ltd\nHangzhou DAC Biotechnology Co., Ltd.", "source_org_type": "公司", "row_number": 138, "target_meta": "EGFR", "MOA_meta": "抗体偶联药物"}, {"drug_name": "ABK-EGFR-1", "company": "Abbisko Therapeutics", "org_type": "公司", "target": "EGFR C797S", "modality": "inhibitor", "importance_level": "中", "total_score": 70.5, "institution_score": 75, "track_score": 85, "milestone_score": 40, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "ABK-EGFR-1为第四代EGFR C797S抑制剂，针对三代TKI耐药突变，具有优秀选择性和脑渗透性；Abbisko为国内头部biotech，但摘要被embargo，仅披露发现与表征阶段为preclinical早期，无具体数据，里程碑价值有限。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11457", "id": "fp7M_5wBZznHJdnt_W3O", "source_drug_name": "ABK-EGFR-1", "title": "Discovery and characterization of ABK-EGFR-1, a 4th generation EGFR C797S Inhibitor with excellent selectivity and brain penetration", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Abbisko Therapeutics", "source_org_type": "公司", "row_number": 146, "target_meta": "EGFR C797S", "MOA_meta": "抑制剂"}, {"drug_name": "CXB-7138", "company": "CoBX Bio Co., Ltd", "org_type": "公司", "target": "GSPT1/ZFP91", "modality": "molecular glue degrader", "importance_level": "中", "total_score": 70.5, "institution_score": 45, "track_score": 90, "milestone_score": 75, "field_heat_score": 85, "bonus_score": 8, "brief_reason": "CXB-7138为首创的双靶点GSPT1/ZFP91分子胶降解剂，采用新型非传统骨架，针对PDAC显示广谱亚纳摩尔级活性及体内口服有效，机制新颖且PDAC领域亟需创新疗法。机构为2024年成立的韩国新兴Biotech，得分受限，但热门分子胶+双靶点+PDAC未满足需求推动赛道与领域热度较高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8734", "id": "fFXM_5wBX1NQZOEH-LG5", "source_drug_name": "CXB-7138", "title": "CXB-7138, A novel GSPT1/ZFP91 dual molecular glue degrader, for targeted treatment of pancreatic ductal adenocarcinoma", "abstract_text": "Background: Pancreatic ductal adenocarcinoma (PDAC) remains one of the most lethal malignancies, driven by profound intertumoral heterogeneity and a dense tumor microenvironment that limits the effectiveness of current therapies. GSPT1 (eRF3a), a translation termination GTPase historically considered “undruggable,” has recently become targetable through cereblon (CRBN)-mediated protein degradation. ZFP91, an atypical E3 ligase and transcriptional regulator, is also highly expressed in PDAC and correlates with poor clinical outcomes. Here, we present CXB-7138, a CRBN-recruiting molecular glue degrader built on a novel, nontraditional chemical scaffold, designed to induce selective degradation of both GSPT1 and ZFP91. To our knowledge, CXB-7138 represents the first dual-target GSPT1/ZFP91 degrader leveraging CRBN for therapeutic intervention in PDAC.\nMethods: A panel of PDAC and non-PDAC cancer cell lines was treated with CXB-7138, and viability was assessed across genetically diverse models. Degradation of GSPT1 and ZFP91 was quantified by proteomics, Western blotting, and HiBiT-based assays. Antitumor activity was evaluated in a subcutaneous PDAC xenograft model following oral administration, with tumor volume and body weight monitored longitudinally.\nResults: CXB-7138 exhibited potent antiproliferative activity across a broad spectrum of cancer cell lines—including but not limited to PDAC—with IC₅₀ values in the sub-nanomolar to double-digit nanomolar range. Within PDAC models, a trend toward increased sensitivity was observed in cell lines harboring SMAD4 alterations, suggesting a potential genomic determinant of CXB-7138 responsiveness. Comparative proteomic profiling confirmed that the compound’s pharmacologic effects arise from selective and sustained CRBN-mediated degradation of both GSPT1 and ZFP91. In vivo, oral single-agent CXB-7138 inhibited tumor growth in a PDAC xenograft model, demonstrating potent antitumor efficacy with favorable tolerability.\nConclusions: CXB-7138 is a first-in-class CRBN-recruiting dual molecular glue degrader targeting GSPT1 and ZFP91 through a nontraditional scaffold. Its broad antiproliferative activity, molecularly defined sensitivity patterns, and strong in vivo efficacy position CXB-7138 as a highly promising therapeutic strategy for PDAC, a malignancy in urgent need of new treatment options.", "source_company": "CoBX Bio Co., Ltd", "source_org_type": "公司", "row_number": 182, "target_meta": "GSPT1,ZFP91", "MOA_meta": "降解剂"}, {"drug_name": "HEC-922", "company": "HEC Pharma", "org_type": "公司", "target": "CDH17 × 4-1BB", "modality": "bispecific antibody", "importance_level": "中", "total_score": 70.5, "institution_score": 65, "track_score": 85, "milestone_score": 55, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "HEC-922为靶向CDH17的4-1BB双特异性抗体，通过肿瘤特异性激活4-1BB实现T细胞激活并降低系统毒性，针对CDH17阳性胃肠道肿瘤；HEC Pharma为中国有实力的创新药企但非顶级，赛道热门（双抗+4-1BB肿瘤免疫+新兴CDH17靶点），处于preclinical但有较好模型数据和平台验证，综合热度较高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9647", "id": "3lXM_5wBX1NQZOEH-LG6", "source_drug_name": "HEC-922", "title": "HEC-922:A CDH17-4-1BB bispecific antibody targeting CDH17 positive tumors shows potent anti-tumor activity", "abstract_text": "HEC-922 is a novel bispecific agonistic antibody targeting Cadherin-17(CDH17) and the immune agonistic receptor 4-1BB for the treatment of CDH17-positive tumors, particularly gastrointestinal tumors. CDH17 is a tumor associated antigen highly expressed in various tumors, including colorectal cancer, gastric cancer, and neuroendocrine tumors. Activating monoclonal antibodies against 4-1BB have shown clinical efficacy but was limited by systemic toxicity. The design of HEC-922 enables CDH17-dependent agonism of 4-1BB in the presence of CDH17 positive tumor cells, enabling tumor specific T cell activation while minimizing systemic immune toxicity. A high affinity nanobody against CDH17 and a nanobody against 4-1BB were identified for the construction of HEC- 922 containing an ADCC-silenced Fc. HEC-922 shows potent co-binding to both CDH17 and 4-1BB targets and is cross-reactive to the Rhesus macaque. In an assay using 4-1BB high expression 293 cells with NFkB-luciferase reporter, HEC-922 mediated 4-1BB activation in the presence of CDH17 positive cells but not CDH17 negative cells. HEC-922 demonstrated effective tumor growth inhibition in xenograft models of CDH17 positive tumor lines, restored the function of immune cells, reduced the proportion of exhausted T cells, and achieved a sustained and potent anti-tumor effect. Initial drug feasibility and toxicity studies results of HEC-922 were favorable. Overall result demonstrated that HEC- 922 is a promising candidate for CDH17 positive cancer immunotherapy.HEC-921, another bispecific antibody developed on the same 4-1BB platform with Ly6G6D as the targeted tumor antigen, has completed Dose Range Finding (DRF) study in cynomolgus monkeys, with a no-observed-adverse-effect level (NOAEL) of 100 mg/kg, validating the safety of the 4-1BB platform.", "source_company": "HEC Pharma", "source_org_type": "公司", "row_number": 203, "target_meta": "CDH17,4-1BB", "MOA_meta": "双特异性抗体"}, {"drug_name": "HC029", "company": "Hongcheng Biopharma", "org_type": "公司", "target": "ITGB6", "modality": "ADC", "importance_level": "中", "total_score": 70.5, "institution_score": 55, "track_score": 85, "milestone_score": 75, "field_heat_score": 80, "bonus_score": 8, "brief_reason": "HC029为针对ITGB6的构象选择性ADC，靶向疾病特异性激活态ITGB6，实现肿瘤选择性杀伤。Hongcheng Biopharma为国内中小型biotech，ADC+新型构象选择机制在preclinical阶段显示强效抗瘤活性及优秀安全性，赛道热度高但机构非头部导致总分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4436", "id": "LJ7M_5wBZznHJdnt_W3O", "source_drug_name": "HC029", "title": "Development of conformation selective ITGB6 ADC", "abstract_text": "Integrin β6 (ITGB6), an epithelial receptor upregulated in fibrotic diseases and epithelial-derived cancers, drives tumor progression by regulating immunosuppression, therapeutic resistance, and metastatic processes. Conventional antibodies lack conformational specificity, often resulting in on-target, off-tumor toxicity. To address this, we developed HC029, a novel activation-state-selective anti-ITGB6 monoclonal antibody and antibody-drug conjugate (ADC) designed to specifically target disease-specific ITGB6 conformation while sparing physiological state ITGB6 unaffected. HC029 binds to a unique conformational epitope exposed on activated ITGB6, achieving 100-fold selectivity for disease-specific ITGB6. Binding affinity increases proportionally with disease severity, as demonstrated by enhanced HC029 ITGB6 engagement in the presence of cancer associated fibroblast (CAF) and latency-associated peptide (LAP) predominantly present in tumor microenvironment. HC029 demonstrated weak and partial inhibition on pathological ITGB6 signaling pathway while preserving physiological ITGB6 function. Furthermore, HC029 incorporates an Fc-silenced human IgG1 which further mitigates off target toxicity. HC029 conjugated with camptothecin derivatives (HC029-CPT) retains ITGB6 conformation-dependent binding, selectively kills cancer cells in the presence of CAF and LAP while sparing cells under physiological conditions. In vivo, HC029-CPT demonstrated potent antitumor activity across multiple PDX and CDX in vivo models including NSCLC, HNSCC, and BLCA, with no significant weight loss or severe toxicity observed. Exploratory pharmacokinetic and toxicology studies in non-human primate demonstrated that HC029-CPT has a maximum tolerated dose (MTD) exceeding 60 mg/kg, with no drug-related mortality observed. Comprehensive evaluations revealed no significant hematological, biochemical, coagulation, or histopathological abnormalities in potential target organs. HC029-CPT exhibited typical ADC pharmacokinetics in cynomolgus monkeys, with dose-proportional exposure of the intact ADC, total antibody, and payload. The linker-payload was highly stable in both in vitro and in vivo studies, with minimal payload release (<0.0001%) from the ADC in plasma. Combining ITGB6 disease state selectivity, unique conformational epitope, effector null Fc, extra stable linker payload and safety profile, HC029-CPT expects to achieve a much broader therapeutic window compared to conventional ITGB6 ADC targeting therapeutics.", "source_company": "Hongcheng Biopharma", "source_org_type": "公司", "row_number": 262, "target_meta": "ITGB6", "MOA_meta": "抗体偶联药物"}, {"drug_name": "novel CRBN molecular glue ternary binders", "company": "HitChem", "org_type": "公司", "target": "CRBN", "modality": "molecular glue", "importance_level": "中", "total_score": 70.5, "institution_score": 65, "track_score": 95, "milestone_score": 45, "field_heat_score": 85, "bonus_score": 3, "brief_reason": "药物为新型CRBN molecular glue三元复合物结合剂，靶向CRBN以诱导底物降解，属于热门的分子胶降解剂赛道。HitChem为专注CADD与化合物库的中小型biotech公司，非头部MNC，处于hit identification早期阶段导致里程碑分数较低，但赛道热度高且有AI辅助库构建亮点。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6487", "id": "KlXM_5wBX1NQZOEH-LG5", "source_drug_name": "novel CRBN molecular glue ternary binders", "title": "Identification of novel CRBN molecular glue ternary binders from a highly diverse CRBN MG library", "abstract_text": "High-throughput screening (HTS) of cereblon (CRBN) molecular glue (MG)-biased libraries remains a key strategy for proof-of-concept studies and hit identification against emerging targets. Because the CRBN binding pocket and its induced interface can adopt multiple conformations, and the substrate binding pocket is often unpredictable at the early stages of discovery, the structural diversity of both CRBN binders and substrate-recognition motifs is crucial to screening efficiency.In this work, we constructed a high-quality, CRBN MG-biased library derived from more than 40 validated CRBN binders. To further enhance chemical diversity, we introduced novel fragments using a tailored AI-based molecular generation model, designed to maximize variations in substrate-binding motifs. HTS case studies demonstrated that this library effectively identified CRBN-substrate ternary binders and degraders with unique scaffolds, representing promising starting points for further optimization.", "source_company": "HitChem", "source_org_type": "公司", "row_number": 338, "target_meta": "CRBN", "MOA_meta": "分子胶"}, {"drug_name": "AP Interceptors", "company": "Apertor Pharmaceuticals", "org_type": "公司", "target": "KRAS", "modality": "molecular glue", "importance_level": "中", "total_score": 70.5, "institution_score": 75, "track_score": 90, "milestone_score": 40, "field_heat_score": 85, "bonus_score": 3, "brief_reason": "AP Interceptors为新型双功能分子胶（bisteric molecules），通过招募FKBP家族蛋白选择性破坏包括KRAS在内的癌蛋白PPIs，实现抗肿瘤活性。机构为美国新兴biotech（曾获Series A融资但近期破产），赛道热门（molecular glue + PPI disruption + KRAS），但仅preclinical细胞水平演示，开发阶段早期。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8725", "id": "dFXM_5wBX1NQZOEH-LG5", "source_drug_name": "AP Interceptors", "title": "Disabling oncogenic signaling with Apertor Interceptors - Proximity inducing bisteric molecules", "abstract_text": "All proteins including those encoded by corrupted DNA in diseased tissues, convey cellular instructions in partnership with other physically interacting proteins. Disrupting these protein-protein interactions (PPIs) to achieve therapeutic goals face a number of daunting chemistry challenges, including the shallow chemical-target interfaces to achieve selective PPI disruption typically found in cell membrane penetrant small molecules. Here we introduce bisteric molecules (AP Interceptors) that are able to traverse the cell membrane and recruit abundantly expressed members of the intracellular FKBP protein family to achieve selective disruption of PPIs essential to the function of several oncogenic driver proteins. We demonstrate the durable effects of AP Interceptors in blocking the growth of cancerous cells harboring alterations in KRAS and present a mechanistic account of their anti-cancer activity.", "source_company": "Apertor Pharmaceuticals", "source_org_type": "公司", "row_number": 388, "target_meta": "KRAS", "MOA_meta": "分子胶"}, {"drug_name": "CD3 nanobody-centric TCE platform", "company": "Guangdong Fapon Biopharma Inc.", "org_type": "公司", "target": "未披露", "modality": "TCE", "importance_level": "中", "total_score": 70.5, "institution_score": 65, "track_score": 85, "milestone_score": 55, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "该平台基于人/食蟹猴交叉反应CD3 nanobody构建TCE，核心优势在于提升临床转化中的安全性、可开发性和T细胞激活调控，但未披露具体靶点。机构为国内创新biotech，赛道TCE+nanobody热度高但仍处平台preclinical阶段。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5121", "id": "gVXM_5wBX1NQZOEH-LG5", "source_drug_name": "CD3 nanobody-centric TCE platform", "title": "Human-cynomolgus cross-reactive CD3 nanobody-centric TCE platform enhances clinical translation", "abstract_text": "T-cell engagers (TCEs) have emerged as a research hotspot in recent years, owing to their ability to precisely mediate T cell killing of target cells. However, their clinical translation is frequently hindered by core challenges: insufficient target specificity, inadequate preclinical safety risk assessment, and poor developability. Thus, an advanced technological platform is urgently needed to break through these barriers and facilitate the efficient translation of TCEs from basic research to clinical applications.\nHere, we established a TCE platform with distinctive technological advantages. Its core highlight lies in the integration of nanobodies targeting the first and second signals of T-cell activation, which possess cross-reactive binding activity between human and cynomolgus monkey, a feature provides crucial support for the preclinical safety assessment. Verification data demonstrates that the TCEs armed with our CD3 nanobody not only exhibit excellent cytotoxicity but also demonstrate favorable safety profiles and robust developability. Nanobodies not only meet the requirements of diverse structural design but also, due to their relatively small molecular weight, are best suited for in vivo TCE development. Currently, relying on the core components of this platform, we have initiated the development of three types of differentiated TCE projects:secondary signal enhanced TCEs, biased activation TCEs and dual-target TCEs. These core components and TCE projects will provide crucial support for achieving excellent therapeutic efficacy in oncology and autoimmune diseases.", "source_company": "Guangdong Fapon Biopharma Inc.", "source_org_type": "公司", "row_number": 396, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "a novel hydrophilic TOPO1 inhibitor payload", "company": "Dong-A ST Research Headquarter", "org_type": "公司", "target": "未披露", "modality": "ADC", "importance_level": "中", "total_score": 70.5, "institution_score": 65, "track_score": 85, "milestone_score": 60, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "采用新型亲水性TOPO1抑制剂作为ADC payload，结合双特异性抗体平台针对异质性肿瘤显示体外体内优效，体现潜在克服单靶点ADC局限性。Dong-A ST为韩国成熟制药公司（非全球头部MNC），ADC+双抗+新型亲水payload赛道热度高，处于preclinical展示积极数据阶段。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5394", "id": "3FXM_5wBX1NQZOEH-LG6", "source_drug_name": "a novel hydrophilic TOPO1 inhibitor payload", "title": "Optimal targeting of heterogeneous tumors using highly developable bispecific antibody drug conjugates based on an improved heterodimerization platform and precisely controlled conjugation of a novel payload", "abstract_text": "We describe the construction of bispecific antibody drug conjugates (ADCs) against multiple target combinations that are clinically correlated, and show that bispecific ADCs have the potential for improved efficacy in heterogeneous tumors compared to single targeted ADCs. Although single-target antibody drug conjugates (ADCs) are highly efficacious in numerous tumor indications, many patients still relapse following ADC therapy due to multiple factors, including inefficient tumor delivery, drug resistance, and antigen escape due to tumor heterogeneity. Thus, there is a high need for developing next generation ADCs that can overcome these limitations. Dual targeting using bispecific antibody-drug conjugates (bsADCs) is an approach that can address important issues such as insufficient targeting due to intra-tumoral expression heterogeneity. Bispecific ADCs are currently being investigated in discovery and early clinical pipelines, but challenges still remain such as selecting optimal target combinations, generating high-quality homogeneous ADC compounds, and optimizing the various ADC components to establish an effective therapeutic window. To develop bispecific antibody drug conjugates, we selected target combinations based on bioinformatics and clinical co-expression. Several in-house platforms were leveraged to create a workflow for rapidly generating bispecific ADCs: (1) an efficient heterodimerization platform for rapidly obtaining native IgG bispecific antibodies from parental monoclonal antibodies, (2) a novel hydrophilic TOPO1 inhibitor payload with an enzyme-cleavable linker, and (3) site-specific conjugation to create ADCs with precisely controlled drug-to-antibody ratio (DAR). A series of bispecific antibodies were constructed against rational combinations of co-expressed targets, and highly homogeneous DAR2 ADCs were obtained by conjugating the payload using Abclick® platform. The bsADCs thus created are less prone to CMC and developability liabilities due to their low hydrophobicity and minimal structural deviation from native IgG. Furthermore, the bispecific ADC showed improved anti-tumor activity in vitro and in vivo compared to the parental mono-targeted ADCs. Together, these results highlight a practical path toward the development of ADCs with improved efficacy in heterogeneous tumors.", "source_company": "Dong-A ST Research Headquarter", "source_org_type": "公司", "row_number": 464, "target_meta": "not available", "MOA_meta": "抗体偶联药物"}, {"drug_name": "small-molecule hits", "company": "Vipergen Aps", "org_type": "公司", "target": "未披露", "modality": "inhibitor", "importance_level": "中", "total_score": 70.5, "institution_score": 65, "track_score": 85, "milestone_score": 55, "field_heat_score": 75, "bonus_score": 3, "brief_reason": "针对癌相关转录因子（TF）的细胞内DEL筛选发现小分子hits，靶点未具体披露但机制创新解决TF“不可成药”难题。Vipergen作为DEL技术专注CRO型biotech机构分较高，热门小分子+TF赛道热度高，但仍处早期筛选验证阶段无明确临床里程碑。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5605", "id": "IlXM_5wBX1NQZOEH-LK6", "source_drug_name": "small-molecule hits", "title": "DELs in cells: Small-molecule hits for transcription factor identified by intracellular DNA-encoded library screening", "abstract_text": "Transcription factors (TFs) are high value yet challenging therapeutic targets in oncology. Most are considered “undruggable” due to the lack of well-defined small-molecule binding pockets, and the presence of extensive intrinsically disordered regions and shallow protein-protein interaction surfaces. Their active conformations further depend on post-translational modifications, cofactors, and the intracellular milieu - conditions difficult to recapitulate in vitro - therefore, strategies that interrogate TFs in their native cellular environment are preferable. DNA-Encoded Libraries (DELs) provide ultra-high-throughput access to small-molecule binders, but a complicating factor for screening DNA-binding proteins is false positives arising from barcode sequences that resemble native binding motifs. Mutant TF versions engineering to disrupt DNA-binding domains can reduce this issue but risks compromising TF structure and function. Therefore, screening full-length proteins appear highly desirable. Here, clusters of small-molecule hits were identified in an intracellular DEL screen against a full-length, cancer-relevant TF and positively validated in orthogonal assays. Importantly, in the screen, a duplex DNA containing the cognate binding motif was included and successfully suppressed barcode-mediated artifacts. A parallel screen including unrelated duplex DNA confirmed retention of sequence-specific TF-DNA interactions showing that the DNA-binding activity of the TF was intact during the screening. These findings demonstrate that intracellular DEL screening can overcome key mechanistic limitations in targeting transcription factors and enable robust discovery of small-molecule binders to functional, full-length TFs - expanding the druggable space for oncogenic transcriptional regulators previously inaccessible to small-molecule approaches.", "source_company": "Vipergen Aps", "source_org_type": "公司", "row_number": 512, "target_meta": "not available", "MOA_meta": "抑制剂"}, {"drug_name": "YT-DP", "company": "Glyco-therapy Biotechnology Co. Ltd.", "org_type": "公司", "target": "未披露", "modality": "ADC", "importance_level": "中", "total_score": 70.5, "institution_score": 45, "track_score": 90, "milestone_score": 75, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "YT-DP为基于糖基偶联的双负载ADC平台，整合Topo I抑制剂和微管抑制剂双机制负载，实现协同抗瘤和旁观者效应。机构为2019年成立的中国杭州初创Biotech，赛道为热门双负载ADC且展示优于DS-8201的CDX模型活性及良好安全性，preclinical强度较高因此综合打分为中偏高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5685", "id": "yVXM_5wBX1NQZOEH-LK6", "source_drug_name": "YT-DP", "title": "YT-DP: A glyco-conjugation-based dual-payloads ADC platform", "abstract_text": "Dual-payloads antibody-drug conjugates (ADCs) represent a promising next-generation modality to enhance antitumor efficacy, achieve synergistic effects, and overcome tumor heterogeneity and therapeutic resistance. However, their development faces several key challenges, including: (i) identifying payload combinations that maintain efficacy within a shared safety window without single-agent dominance; (ii) achieving precise and efficient assembly of distinct payloads into antibodies with controlled drug-to-antibody ratios (DARs); and (iii) ensuring robust stability, in vivo efficacy, and favorable safety profiles. To address these challenges, we developed YT-DP, a glyco-conjugation-based dual-payloads ADC platform that enables the incorporation of two distinct mechanism-of-action (MOA) payloads into a single antibody molecule through a one-step glyco-conjugation strategy. This system allows flexible DAR configurations (e.g., DAR 2+2 or DAR 2+4). The YT-DP platform integrates our proprietary cleavable-linker-topoisomerase I inhibitor payload (CLTp) technology (YT-CLTp) with a microtubule inhibitor (MTI) via the YTConju glyco-conjugation system. The YT-CLTp series comprises tunable payload candidates with adjustable target and bystander killing activities, demonstrating superior anti-tumor potency compared with “GGFG-Dxd” in multiple CDX models when conjugated to antibodies. We generated trastuzumab-based dual-payloads ADCs (Tras-DPs) containing an MTI and distinct CLTps at different DARs (DAR 2+2 and DAR 2+4). Tras-DPs exhibited high homogeneity, excellent thermal and plasma stability, and potent synergistic antitumor activity with strong by-stander effects. Notably, Tras-DPs demonstrated markedly superior antitumor activity compared with DS-8201, as well as the corresponding single-payload ADCs or their combinations, in CDX models. In addition, the dual-payloads ADCs showed favorable pharmacokinetic (PK) properties and safety profiles in rat studies. In summary, the YT-DP platform provides a robust and versatile strategy for constructing homogeneous, stable, and synergistic dual-payloads ADCs with tunable DARs. Its broad compatibility with various antibody formats, including Fc-containing bispecific antibodies, underscores its potential to enable next-generation ADCs with an enhanced therapeutic index.", "source_company": "Glyco-therapy Biotechnology Co. Ltd.", "source_org_type": "公司", "row_number": 616, "target_meta": "not available", "MOA_meta": "抗体偶联药物"}, {"drug_name": "T cell engager receptor (TCE-R)", "company": "Inceptor Bio", "org_type": "公司", "target": "未披露", "modality": "other", "importance_level": "中", "total_score": 70.5, "institution_score": 65, "track_score": 85, "milestone_score": 55, "field_heat_score": 80, "bonus_score": 4, "brief_reason": "TCE-R是一种通过LNP-mRNA递送的嵌合适配蛋白，可使现有CD3靶向TCE激活先天免疫细胞，增强抗肿瘤免疫并促进抗原扩散和新机制协同。Inceptor Bio作为专注实体瘤细胞治疗的临床阶段美国biotech公司，赛道（TCE+先天免疫协同+体内mRNA递送）创新热度高，但仍处preclinical阶段且靶点未明确导致总分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9434", "id": "2VXM_5wBX1NQZOEH-LK6", "source_drug_name": "T cell engager receptor (TCE-R)", "title": "Enhancing anti-tumor immunity via in vivo LNP delivery of a universal chimeric adapter protein to activate innate immune cells through T cell engagers", "abstract_text": "T cell engagers (TCEs) have achieved remarkable successes both in liquid and solid tumors. However, relapses tend to occur in a significant fraction of patients, driven by antigen escape or T cell exhaustion. Currently, TCEs are unable to engage innate immune responses and thereby fail to leverage the innate immune system’s crucial support functions, such as inducing a pro-inflammatory environment and promoting antigen spread and T cell licensing against tumor neoantigens.\nHere we describe a chimeric adaptor protein that renders innate immune cells engageable by existing T cell engagers. This T cell engager receptor (TCE-R) is comprised of an extracellular domain that is recognized by all CD3-targeting TCEs, and a set of intracellular signaling domains that drive innate cell effector function upon TCE binding. Following initial administration of the TCE alone to induce tumor debulking, TCE-R is delivered in vivo using mRNA encapsulated in a lipid nanoparticle (LNP) allowing trafficking of pro-inflammatory innate immune cells to the tumor, inducing a broader TCE-driven anti-tumor response.\nIn a monocyte cell line stably expressing TCE-R, we have demonstrated TCE-mediated phagocytosis of target cancer cells as well as TCE-driven induction of pro-inflammatory signaling pathways. Further, TCE-R delivered as an LNP-encapsulated mRNA to primary human macrophages and dendritic cells in vitro resulted in expression of TCE-R on the cell surface, demonstrating the ability to deliver the transgene to relevant lineages of the innate immune system. Lastly, in vivo delivery of TCE-R LNP to innate immune cells in immune competent Balb/c and immunocompromised NSG mice has been demonstrated through surface expression of the human TCE-R on multiple myeloid cell lineages.\nTaken together, our data lay the foundation to endow any anti-CD3 TCE with the ability to engage innate immune cells, recruit them to the tumor site, activate them in situ, and to leverage new effector functions to aid, broaden, and expand TCE-driven T cell responses ultimately leading to antigen spread, T cell licensing and durable remission.", "source_company": "Inceptor Bio", "source_org_type": "公司", "row_number": 629, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "CRBN-based pan-KRAS degraders", "company": "University of Michigan", "org_type": "大学", "target": "pan-KRAS", "modality": "PROTAC", "importance_level": "中", "total_score": 70.5, "institution_score": 35, "track_score": 95, "milestone_score": 85, "field_heat_score": 90, "bonus_score": 4, "brief_reason": "采用CRBN-based PROTAC机制靶向pan-KRAS（包括G12D、G12V、G12C），属于当前最热门的KRAS降解赛道之一；虽然来自大学机构，但展现出<1 nM DC50/IC50、优秀跨物种PK以及在难治模型中>90%肿瘤消退的强preclinical数据，综合潜力较高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6442", "id": "eFXM_5wBX1NQZOEH-LO6", "source_drug_name": "CRBN-based pan-KRAS degraders", "title": "Design and synthesis of highly efficacious CRBN-based pan-KRAS degraders targeting cancers with KRAS G12D, G12V and G12C mutations", "abstract_text": "Oncogenic mutation of KRAS is one of the most promising targets for cancer. Treatment with inhibitors inevitably lead to rapid onset of resistance, and loss of therapeutic effect after months. KRAS PROTACs may offer superior efficacy by eliminating mutated protein, disrupting scaffolding function and activating immune response, thus overcoming the rapid development of resistance. Using new E3 ligands developed in house, our compounds achieved less than 1 nM DC50 and IC50 in in vitro assays with G12D, G12V and G12C mutated cell lines. They exhibited excellent pharmacokinetic and pharmacodynamic properties in mice, and outstanding pharmacokinetic in rats, dogs, and monkeys. At 10 mg/kg, qW, the compounds achieved a remarkable TGI of over 92% in SW620 xenograft, a robust and challenging model of KRASG12V mutation. Additionally in an efficacy study with mice bearing SW1990 xenograft, at 10 mg/kg, qW, the compounds regressed the tumors by over 90%.", "source_company": "University of Michigan", "source_org_type": "大学", "row_number": 729, "target_meta": "KRAS", "MOA_meta": "PROTAC"}, {"drug_name": "site-specific dual-payload ADC platform", "company": "OBI Pharma, Inc", "org_type": "公司", "target": "未披露", "modality": "ADC", "importance_level": "中", "total_score": 70.5, "institution_score": 65, "track_score": 90, "milestone_score": 55, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "该平台为下一代位点特异性双负载ADC技术，采用糖基化工程和专有连接子实现双不同payload灵活组合，机制新颖但靶点未明确披露。OBI Pharma为台湾临床阶段biotech，在ADC领域有一定布局和临床推进（如OBI-902已进I/II期），赛道ADC+双负载热度高，preclinical展示优于单负载基准但整体里程碑仍早期。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5403", "id": "gFXM_5wBX1NQZOEH-LS6", "source_drug_name": "site-specific dual-payload ADC platform", "title": "Advancing ADC therapeutics with next-generation site-specific glycan conjugation and dual-payload flexibility", "abstract_text": "The unique technology by enabling site-specific glycan-based conjugation via a proprietary dual-function enzyme offers an innovative approach for developing antibody-drug conjugates (ADCs). This advanced technology facilitates the production of homogeneous ADCs at a specific drug-to-antibody ratio (DAR) from DAR2 to DAR16, while maintaining the integrity and function of the native antibody. A key feature of the technology is its proprietary linker, specifically designed to enhance payload stability and enable selective release within the tumor, thereby potentially broadening the therapeutic index.\nExpanding upon its core capabilities, the new technologies serve as a dual-payload platform, enabling the development of site-specific ADCs carrying two distinct payloads. This technology allows for flexible DAR construction, including both equal and asymmetric payload ratios, providing versatility to tailor ADCs for optimized therapeutic outcomes. Moreover, the ability to specify distinct conjugation sites further enhances its flexibility for diverse payload combinations, including cytotoxic agents, immunomodulators, anti-tumor inhibitors, and degraders. The platform also accommodates both mono- and multi-specific antibodies, broadening its applicability across therapeutic modalities.\nHere we used microtubule inhibitor and Topoisomerase I inhibitor to demonstrate the site-specific dual-payload platform. In preclinical studies, the site-specific dual-payload ADCs exhibited superior cytotoxicity and promising antitumor activity in various tumor models, compared to approved and benchmark single payload ADCs, underscoring their potential for enhanced antitumor efficacy. Importantly, these ADCs maintained structural integrity and\navoided antibody aggregation. These features provide a strong foundation for the future clinical development of biomolecules derived from this site-specific dual-payload technology.\nThrough the integration of glycan engineering, dual-function enzymatic control, proprietary linker chemistry, and flexible payload conjugation, the site-specific dual-payload technology suite provides a robust and adaptable solution to overcome key limitations in current ADC design. Continued innovation and clinical translation of the site-specific dual-payload platform may unlock new therapeutic possibilities to overcome drug resistance and is applicable across oncology and beyond.", "source_company": "OBI Pharma, Inc", "source_org_type": "公司", "row_number": 923, "target_meta": "not available", "MOA_meta": "抗体偶联药物"}, {"drug_name": "AI-designed immune sensor-enhanced CAR-T cells", "company": "Edity Therapeutics", "org_type": "公司", "target": "未披露", "modality": "CAR", "importance_level": "中", "total_score": 70.5, "institution_score": 65, "track_score": 85, "milestone_score": 55, "field_heat_score": 80, "bonus_score": 4, "brief_reason": "该药物为AI优化STING/MAVS通路免疫传感器增强型CAR-T，通过CAR信号特异激活局部I型干扰素和炎症反应，改善实体瘤免疫冷微环境。Edity Therapeutics为以色列新兴biotech，preclinical阶段在异种移植模型显示显著优于常规CAR-T，赛道热门但具体靶点和临床适应症未披露。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3668", "id": "hVXM_5wBX1NQZOEH-LS6", "source_drug_name": "AI-designed immune sensor-enhanced CAR-T cells", "title": "AI-designed immune sensor-enhanced CAR-T cells for potent solid tumor immunotherapy", "abstract_text": "Immune-based therapies have revolutionized cancer treatment; however, their efficacy in solid tumors remains limited. This is primarily due to the immunosuppressive tumor microenvironment (TME) and insufficient induction of systemic anti-tumor immunity. To overcome these barriers, Edity Therapeutics has developed an AI-guided platform that integrates engineered innate immune sensors into CAR-T cells. These sensors are designed to initiate a localized antiviral-like immune response upon antigen engagement. Immune sensors derived from the STING and MAVS pathways were computationally optimized to generate constitutively active, yet controllable, derivatives that drive Type I interferon and pro-inflammatory cytokine production. These sensor modules were fused to a navigator domain, ensuring their activation is exclusively upon CAR signaling, thereby confining immune stimulation to the tumor site. Hundreds of sensor variants were designed and screened in vitro for functional potency. Lead candidates exhibiting strong immuno-stimulatory activity were incorporated into CAR-T constructs and evaluated in SCID-Beige xenograft models. In these models, sensor-enhanced CAR-T cells demonstrated significantly superior tumor control compared to conventional CAR-T counterparts. By locally provoking inflammation, this approach will convert the immune-cold TME into an inflamed tumor milieu, potentially enabling robust anti-tumor responses without inducing peripheral adverse effects. The platform is currently being advanced toward clinical development, with two solid tumor indications selected based on antigen expression, tumor accessibility, and translational readiness. These next-generation CAR-T products represent a new class of cell therapies that couple precise tumor targeting with controlled autonomous immune activation, offering a transformative approach for the treatment of solid malignancies while improving the therapeutic index.", "source_company": "Edity Therapeutics", "source_org_type": "公司", "row_number": 925, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "a novel tumor-microenvironment-responsive pro-TCE therapy", "company": "Bliss Biopharmaceutical Co., Ltd", "org_type": "公司", "target": "未披露", "modality": "pro-TCE", "importance_level": "中", "total_score": 70.5, "institution_score": 75, "track_score": 85, "milestone_score": 40, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "药物为肿瘤微环境响应型pro-TCE（前药形式T细胞衔接剂），旨在降低细胞因子释放以提高实体瘤治疗安全性，但摘要被禁未披露具体靶点或数据。机构为国内临床阶段biotech，曾与Eisai合作ADC并有临床管线，得分较高；赛道TCE热门但pro形式创新，preclinical阶段且无具体里程碑导致总分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11542", "id": "lVXM_5wBX1NQZOEH-LS6", "source_drug_name": "a novel tumor-microenvironment-responsive pro-TCE therapy", "title": "A novel tumor-microenvironment-responsive pro-TCE therapy minimizes cytokine release for safer solid tumor treatment", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Bliss Biopharmaceutical Co., Ltd", "source_org_type": "公司", "row_number": 939, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "single-dose HPV vaccine", "company": "NCI Division of Cancer Epidemiology & Genetics", "org_type": "研究机构", "target": "HPV", "modality": "other", "importance_level": "中", "total_score": 70.5, "institution_score": 60, "track_score": 80, "milestone_score": 70, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "该presentation聚焦单剂HPV疫苗在癌症预防中的潜力，由NCI研究机构主导，靶向HPV病毒预防宫颈癌等；赛道为预防性疫苗领域热度高，单剂方案具重大公共卫生意义，但作为研究机构非商业开发且无具体新药机制细节，得分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11227", "id": "v1XM_5wBX1NQZOEH-LS6", "source_drug_name": "single-dose HPV vaccine", "title": "Single-dose HPV Vaccination: A shot in the arm for cancer prevention", "abstract_text": "There is no abstract associated with this presentation.", "source_company": "NCI Division of Cancer Epidemiology & Genetics", "source_org_type": "研究机构", "row_number": 973, "target_meta": "HPV", "MOA_meta": "其他"}, {"drug_name": "H1L1A1B3-circRNA-IL-12 LNPs", "company": "Baylor College of Medicine", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "中", "total_score": 70.5, "institution_score": 55, "track_score": 85, "milestone_score": 75, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "该平台使用新型离子化脂质纳米粒递送编码IL-12的circRNA，实现肺癌局部持续表达IL-12并激活免疫途径，无明确药物靶点。机构为知名医学院但非产业化头部药企得中偏高分，circRNA+LNP+IL-12局部免疫治疗在肺癌领域具高热度与创新性，动物模型显示显著疗效及TME重塑。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5767", "id": "Vp7M_5wBZznHJdnt_W3O", "source_drug_name": "H1L1A1B3-circRNA-IL-12 LNPs", "title": "Tumor-tailored ionizable lipid nanoparticles facilitate IL-12 circular RNA delivery for enhanced lung cancer immunotherapy", "abstract_text": "mRNA-based immunotherapies are hindered by systemic toxicity and transient expression, necessitating frequent dosing. This is especially problematic for potent cytokines like Interleukin-12 (IL-12), whose use is limited by severe adverse effects.\nTo address this, we developed a platform using circular RNA (circRNA), which offers more sustained protein expression than linear mRNA. A high-throughput combinatorial method (Ugi reaction) was used to screen for ionizable lipids to deliver circRNA to lung tumors. The lead LNP, H1L1A1B3, showed a fourfold increase in circRNA transfection efficiency over the ALC-0315 standard. H1L1A1B3 LNPs were also dual-functional, acting as an immune adjuvant by potently activating NF-κB and IRF innate immune pathways. This LNP was loaded with circRNA encoding IL-12, providing significantly delayed decay in protein expression.\nTherapeutic efficacy was validated in two lung cancer models. In a subcutaneous LLC1 model, a single intratumoral injection of H1L1A1B3-circRNA-IL-12 LNPs delayed tumor progression. Combined with an anti-PD-L1 checkpoint inhibitor, this induced robust tumor regression. Immunological profiling revealed a profound remodeling of the tumor microenvironment (TME), including an eightfold increment in CD45+ leukocytes and enhanced infiltration of CD8+ and CD4+ T cells, increasing the CD8+/Treg ratio.\nSecond, in an orthotopic HKP1 NSCLC model, a single intratracheal administration of the IL-12 circRNA LNPs effectively suppressed lung tumor growth. This local delivery resulted in sustained serum IL-12 and IFN-γ for at least five days but did not cause systemic liver toxicity (normal AST/ALT levels). The treatment successfully recruited immune cells, including CD8+ T cells, to the lung tumors.\nIn conclusion, this work presents a tumor-tailored, dual-function LNP (H1L1A1B3) that efficiently delivers stable IL-12 circRNA and provides intrinsic immunostimulatory effects. The platform enables sustained, localized cytokine expression, remodeling the TME to be immunologically \"hot.\" These results highlight the potential of this LNP-circRNA platform to advance RNA drug delivery, offering a potent and safer immunotherapeutic strategy for lung cancer by overcoming systemic toxicity and transient expression hurdles.", "source_company": "Baylor College of Medicine", "source_org_type": "大学", "row_number": 1009, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "CD19-CAR T cells", "company": "Xcell Biosciences", "org_type": "公司", "target": "CD19", "modality": "CAR", "importance_level": "中", "total_score": 70.5, "institution_score": 65, "track_score": 85, "milestone_score": 60, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "CD19靶向CAR-T细胞通过生理氧浓度+高压条件优化制造工艺，提升体外杀伤和体内抗肿瘤效力，体现制造优化潜力。机构为专注细胞治疗制造平台的美国生物科技公司（非头部MNC），赛道热门但仍处preclinical优化阶段，故综合评分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5197", "id": "lZ7M_5wBZznHJdnt_W3O", "source_drug_name": "CD19-CAR T cells", "title": "Environmental conditioning during CD19-CAR T cell manufacturing impacts antitumor potency in a subcutaneous NALM6 tumor model", "abstract_text": "Chimeric Antigen Receptor (CAR) T cell therapy has transformed outcomes for hematologic malignancies, yet optimizing manufacturing conditions remains critical to improving potency and consistency. We previously demonstrated that culturing CAR-T cells under physiological oxygen and pressurized conditions improved persistence and efficacy in a disseminated NALM6 human ALL model.In this study, we investigated whether these optimized manufacturing conditions similarly improve antitumor activity in a subcutaneous NALM6 xenograft model. CD19-targeted CAR-T cells were expanded under three conditions: standard CO2 incubation (21% O2 + 0 PSI), mild hypoxia with hyperbaric pressure (15% O2 + 5 PSI), reflecting arterial and peripheral blood environments, and hypoxia with hyperbaric pressure (5% O2 + 5 PSI), modeling the solid tumor and bone marrow microenvironments. After a 10-day tumor stage, a dose of 2.5e6 CAR+ T cells achieved complete tumor clearance in all conditions at 20 days post T cell dose, with faster tumor regression under 5% O2 + 5 PSI conditions (7 days post T cell dose) compared to normoxia or mild hypoxia (10 days post T cell dose). These in vivo outcomes were consistent with enhanced in vitro functional activity, characterized by greater cytoxicity at CAR-T-to-effector ratios under 1:30 and increased cytokine production. This consistency mirrors our previous findings in the disseminated model, where CAR-T cells cultured under physiologically relevant conditions demonstrated the in vitro characteristics predictive of in vivo efficacy. Preliminary findings show enhanced potency and persistence under 5% O2 + 5 PSI conditions. To determine whether these manufacturing advantages are sustained at lower CAR-T doses, a dose titration study is currently in progress, with complete results forthcoming.These data highlight the potential of physiological manufacturing with the GMP AVATAR Foundry to enhance CAR-T function and lower effective doses, supporting scalable next-generation cell therapies.", "source_company": "Xcell Biosciences\nXcellbio", "source_org_type": "公司", "row_number": 1050, "target_meta": "CD19", "MOA_meta": "其他"}, {"drug_name": "TA-1", "company": "GemPharmatech Co., Ltd.", "org_type": "公司", "target": "未披露", "modality": "mRNA", "importance_level": "中", "total_score": 70.5, "institution_score": 65, "track_score": 85, "milestone_score": 60, "field_heat_score": 80, "bonus_score": 0, "brief_reason": "TA-1为mRNA癌疫苗，在HLA人源化小鼠模型和PDX中显示抗肿瘤活性并与anti-PD-1协同增效，但靶点/具体抗原未披露。GemPharmatech作为国内领先CRO模型服务商有一定实力，mRNA疫苗赛道热度高但该展示主要为平台验证而非药物里程碑。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3657", "id": "Cp7M_5wBZznHJdnt_W7O", "source_drug_name": "TA-1", "title": "Bridging in vitro screening to in vivo efficacy for cancer vaccines", "abstract_text": "mRNA cancer vaccines represent a next-generation immunotherapy platform with the potential to elicit robust, antigen specific immune responses. Upon in vivo delivery, mRNA vaccines are taken up by antigen-presenting cells (APCs), translated into the tumor associated antigen and presented via MHC molecules to activate adaptive immunity. However, standard mouse models with murine MHC molecules are not suitable for evaluating these MHC-restricted immune responses. GemPharmatech has developed an in vitro and in vivo mRNA vaccine drug evaluation service platform, including the in vitro and in vivo immunogenicity evaluation, in vivo anti-tumor efficacy and safety evaluation. For in vitro immunogenicity, dendritic cells derived from autologous monocytes (moDCs) are matured and loaded with specific antigen peptides using electroporation or administered with LNP-mRNA. The peptide-pulsed moDCs are then co-cultured with T cells from the same donor. The antigen-specific T-cell response is detected by ELISpot or flow cytometry. In vitro immunogenicity evaluation is applicable to early antigen peptide screening, assessing the affinity of antigen peptides for corresponding HLA molecules and their immunostimulatory capacity. For in vivo evaluation of cancer vaccine, GemPharmatech has developed a series of HLA-humanized mouse models across multiple mouse backgrounds including the immunocompetent mice B6, BALB/c, CB6F1 and the immunodeficient NCG derived mice. These models express human HLA molecules, enabling the accurate evaluation of antigen presentation, immunogenicity, and therapeutic efficacy of mRNA vaccines. The HLA-humanized mice exhibit strain-dependent humoral and cellular immune responses, satisfying various evaluation needs. HLA humanized mice exhibited strain specific humoral and cellular immune responses, but are sufficient to satisfy various evaluation needs. CB6F1 exhibited good combination of humoral and cellular immune response to the same immunogen, making them more suitable for assessing vaccine immunogenicity. In NCG-M-hHLA-A2.1 mice engrafted with hematopoietic stem cells, HLA-A2.1-restricted immune responses were observed, reflecting successful reconstitution of human DCs and functional T cells. Therapeutic studies using TA-1 (mRNA vaccine) or anti-PD1 in a patient derived xenograft (PDX) demonstrated that TA-1 or anti-PD-1 inhibited tumor growth, while combination therapy led to greater tumor inhibition. In conclusion, GemPharmatech has established a comprehensive vaccine evaluation platform that integrates in vitro screening with in vivo models to provide more options for preclinical evaluation of tumor vaccines.", "source_company": "GemPharmatech Co., Ltd.", "source_org_type": "公司", "row_number": 1260, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "tri-specific immunocytokine", "company": "Y-Biologics", "org_type": "公司", "target": "未披露", "modality": "tri-specific immunocytokine", "importance_level": "中", "total_score": 70, "institution_score": 65, "track_score": 90, "milestone_score": 50, "field_heat_score": 85, "bonus_score": 3, "brief_reason": "药物为针对PD-1+ T细胞的三特异性免疫细胞因子，通过优化减弱IL-2变体实现PD-1依赖的靶向IL-2递送，靶点未明确披露但机制聚焦PD-1和IL-2R。Y-Biologics为韩国中型抗体biotech公司，非头部MNC或TOP国内biotech，赛道为热门三特异性+细胞因子融合且in vivo验证有效但仍处preclinical优化阶段。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4529", "id": "o1XM_5wBX1NQZOEH-LS6", "source_drug_name": "tri-specific immunocytokine", "title": "Systematic discovery of attenuated IL-2 variants optimized for bispecific antibodies enabling targeted IL-2 delivery to PD-1+T cells", "abstract_text": "Background: Targeted delivery of an interleukin-2 variant (IL-2v) via fusion to an anti-PD-1 antibody has emerged as a promising strategy to overcome resistance to anti-PD-(L)1 therapy. However, unattenuated signaling through the IL-2 receptor β/γ chain (IL-2Rβ/γ), even in the context of cis-delivery to PD-1⁺ cells, can still lead to systemic toxicities. Fusion of IL-2v to bispecific antibodies introduces further challenges associated with dual-antigen targeting and increased risk of adverse events. To address these challenges, we screened IL-2 variants with varying degrees of IL-2Rβ/γ binding that either have IL-2Rα interaction preserved or reduced, for fusion with anti-PD-1-based bispecific antibodies to generate novel tri-specific immunocytokines.\nMethods: IL-2 variants were generated and screened for reduced IL-2Rβ/γ binding using random mutagenesis. Variants were evaluated for manufacturability after bispecific antibody fusion via mammalian cell transient expression and affinity purification for both yield and purity. Binding was determined using Octet® and ELISA, while pSTAT5 activity was evaluated on PD-1 negative and PD-1 positive cells to assess PD-1-dependent IL-2 signaling. Variants were classified into non-α, α-biased, or α-masked categories based on the strength of binding to IL-2Rβ/γ for further development. Selected tri-specific immunocytokines fused with various IL-2v configurations underwent safety and efficacy assessment in vivo using MC38 syngeneic hPD-1 knock-in mouse tumor models.\nResults: We generated a library of IL-2 variants with diverse sequences and, following initial screening, performed additional engineering to further optimize their compatibility with bispecific antibody formats. Selected IL-2 variants were successfully synthesized in a bispecific antibody format with an anti-PD-1 arm, generating fusion proteins that met the acceptable-yield criteria. IL-2 variants showed markedly reduced binding and pSTAT5 activity to both IL-2Rβγ and IL-2Rαβγ compared to wildtype IL-2. The degree of binding attenuation determined whether these variants should be further developed into non-α, α-biased, or α-masked IL-2v. Optimized IL-2v-fused tri-specific immunocytokines showed dramatically attenuated IL-2R which was restored only upon binding to PD-1, demonstrating cis-acting PD-1-dependency. This was further verified in vivo, where selective PD-1-dependent IL-2v signaling translated into significant tumor growth inhibition with minimal toxicity.\nConclusion: Our approach provides a rational framework to fine-tune IL-2v binding affinity for fusion to bispecific antibodies, which can be replicated for the discovery of other affinity-tuned cytokine variants that exert targeted immune activation and therefore, improve the therapeutic index of tri-specific immunocytokines.", "source_company": "Y-Biologics", "source_org_type": "公司", "row_number": 949, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "membrane-bound IL-2 and IL-12 CAR-T cells", "company": "Portal Biotechnologies, Inc.", "org_type": "公司", "target": "未披露", "modality": "CAR", "importance_level": "中", "total_score": 69.5, "institution_score": 65, "track_score": 85, "milestone_score": 55, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "该工程化CAR-T细胞通过递送circRNA实现膜结合IL-2和IL-12的表达，旨在增强CAR-T功能，但靶点未明确披露。机构为2023年成立的早期biotech平台公司（有DARPA合同和知名创始人），赛道为热门的细胞治疗+细胞因子工程，preclinical展示功能表达和规模化潜力。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5203", "id": "tFXM_5wBX1NQZOEH-LK6", "source_drug_name": "membrane-bound IL-2 and IL-12 CAR-T cells", "title": "Combining circular RNA and a silicon membrane-based cell engineering approach to create CAR-Ts with membrane bound IL-2 and IL-12", "abstract_text": "Cell delivery is crucial for cell therapy and drug development, and we have developed a novel mechanoporation technology that allows efficient delivery of a wide range of cargoes to primary cells and cell lines. This technology uses a silicon membrane to temporarily deform cells, creating pores that enable cargo diffusion into the cells. Importantly, this method minimizes disruption to normal gene expression and maintains cellular integrity. It is compatible with various cell types and has been successfully applied in both cell therapy and drug discovery. At Portal, we have successfully delivered CRISPR/Cas9 RNPs, mRNAs, circular RNAs, and siRNAs into T cells, B cells, NK cells, and monocytes. For instance, we achieved over 85% GFP expression and B2M deletion in naive T cells after simultaneous delivery of mRNA and CRIRPR-RNPs. Additionally, we demonstrated the functional expression of a CD19 CAR and membrane-bound IL-2 by delivering two circRNAs. Early data from iPSCs and HSCs show significant potential for stem cell engineering and differentiation. Using a clinical-scale prototype, we have achieved delivery of over 1x10⁹ T cells per minute, resulting in more than 50% knockout efficiency and 90% GFP expression after 7 days of T cell expansion.Our platform also addresses a major barrier to drug development by enabling the delivery of cargoes that are otherwise impermeable to cells, such as small molecules, peptides, PROTACs, DELs, antibodies, and probes. We have successfully delivered a variety of cargos with over 80% efficiency while maintaining high cell viability. The technology has been tested in several cell types, including cancer cell lines, human immune cells, and stem cells. The simplicity of the mechanical delivery method facilitates scalability and integration with liquid handlers for high-throughput applications. This enables rapid and automated screening of molecules previously incompatible with live cell assays, improving drug discovery efficiency. Overall, Portal’s technology offers a scalable, cost-effective solution with the potential to significantly advance both cell therapy and drug discovery. By reducing manufacturing time and cost, it seamlessly integrates into existing clinical and industrial equipment, supporting the development of next-generation cell-based treatments that could revolutionize the treatment of diseases with high unmet clinical needs.", "source_company": "Portal Biotechnologies\nPortal Biotechnologies, Inc.", "source_org_type": "公司", "row_number": 45, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "hSIRPα × hClaudin18.2 bispecific antibody", "company": "GemPharmatech Co., Ltd.", "org_type": "公司", "target": "SIRPα × Claudin18.2", "modality": "bispecific antibody", "importance_level": "中", "total_score": 69.5, "institution_score": 65, "track_score": 85, "milestone_score": 55, "field_heat_score": 80, "bonus_score": 0, "brief_reason": "该双抗靶向SIRPα和Claudin18.2，通过阻断CD47-SIRPα通路增强巨噬细胞吞噬并靶向肿瘤特异抗原Claudin18.2，属于热门免疫肿瘤双抗赛道。GemPharmatech作为国内领先基因工程小鼠模型CRO公司，在preclinical模型中显示显著抗瘤效应，但仍处早期研究阶段，综合热度较高但里程碑有限。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/7160", "id": "i57M_5wBZznHJdnt_W3O", "source_drug_name": "hSIRPα × hClaudin18.2 bispecific antibody", "title": "A novel humanized mouse model for preclinical assessment of anti-CD47 and anti-SIRPΑtherapeutics", "abstract_text": "Background: CD47, a ubiquitously expressed \"don't eat me\" molecular signal, mediates the evasion of tumor cells from phagocytic clearance through specific interaction with signal regulatory protein alpha (SIRPΑ) expressed on the surface of macrophages and dendritic cells. Therapeutic agents targeting the CD47-SIRPΑ pathway promote tumor cell eradication through two well-characterized mechanisms: 1. Blocking antibodies, including monoclonal and bispecific antibodies, interfere with the CD47-SIRPΑ interaction to enhance macrophage-driven phagocytosis of tumor cells; 2. The Fc domain mediates antibody-dependent cellular cytotoxicity (ADCC) and complement-dependent cytotoxicity (CDC). These biological processes further strengthen dendritic cell-mediated antigen presentation and initiate anti-tumor adaptive immune responses, which collectively establishes the CD47-SIRPΑ axis as a high-priority target in immuno-oncology.\nMethods: To support the translational assessment of CD47-targeted therapies, GemPharmatech developed a BALB/c-derived double humanized hCD47/hSIRPα knock-in mouse model, in which the extracellular domains of human CD47 and SIRPΑ were expressed. Successful model construction was verified by detecting the protein expression levels of hCD47 and hSIRPΑ in BALB/c-hCD47/hSIRPΑ mice. This model was used to evaluate the anti-tumor efficacy of the anti-hCD47 antibody Magrolimab (5F9) using a CT26-hCD47 colorectal tumor model—established by engrafting CT26 overexpressing human CD47 into BALB/c-hCD47/hSIRPΑ mice. Given the well-documented toxicity of CD47 blockade, anti-SIRPΑ antibodies were also tested to explore an alternative targeting strategy. Additionally, the anti-tumor efficacy of the hSIRPΑ × hClaudin18.2 bispecific antibody (BsAb) was evaluated in BALB/c-hCD47/hSIRPΑ mice bearing the EMT6-hCD47-hClaudin18.2 triple-negative breast tumor model, where EMT6 cells overexpress both human CD47 and human Claudin18.2.\nResults: Expression of hCD47 and hSIRPΑ in BALB/c-hCD47/hSIRPΑ mice was successfully verified. Administration of the anti-hCD47 antibody induced dose-dependent tumor regression in the established colorectal tumor model. Notably, the hSIRPΑ×hClaudin18.2 bispecific antibody (BsAb) exerted a significant anti-tumor effect in BALB/c-hCD47/hSIRPΑ knock-in mice implanted with EMT6-hCD47-hClaudin18.2 tumor cells.\nConclusions: The BALB/c-hCD47/hSIRPΑ mouse model serves as a clinically relevant tool for evaluating therapeutics targeting the CD47-SIRPΑ pathway within an immuocompetent model. Notably, it addresses key limitations of traditional immunocompromised murine models while providing critical insights into the mechanisms underlying CD47 pathway-mediated tumor clearance, toxicity management, and immune activation.", "source_company": "GemPharmatech Co., Ltd.", "source_org_type": "公司", "row_number": 86, "target_meta": "SIRPα,CLDN18.2", "MOA_meta": "双特异性抗体"}, {"drug_name": "DXA038-CPT113", "company": "Hangzhou DAC Biotechnology Co., Ltd", "org_type": "公司", "target": "GP220/350 和 EGFR", "modality": "ADC", "importance_level": "中", "total_score": 69.5, "institution_score": 65, "track_score": 90, "milestone_score": 50, "field_heat_score": 75, "bonus_score": 3, "brief_reason": "该双特异性ADC同时靶向EBV GP220/350和EGFR，用于EBV阳性鼻咽癌的精准治疗，具有双靶点提升选择性和内化效率的机制优势。机构为专注ADC的国内biotech，平台较强但非头部；赛道为热门ADC+双抗组合，开发处于体外/体内研究阶段故总分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6471", "id": "Bp7M_5wBZznHJdnt_W7O", "source_drug_name": "DXA038-CPT113", "title": "A novel 2+2 IgG-like bispecific antibody-drug conjugate targeting EBV GP220/350 and EGFR for selective treatment of nasopharyngeal carcinoma", "abstract_text": "Nasopharyngeal carcinoma (NPC) is endemic in East and Southeast Asia, with Epstein-Barr virus (EBV) infection as a primary etiological factor. The EBV envelope glycoprotein GP220/350 is highly expressed on EBV-positive NPC cells, serving as a tumor-specific antigen. Epidermal growth factor receptor (EGFR) is also overexpressed in >80% of NPC cases and is a validated therapeutic target (e.g., cetuximab). Bispecific antibodies (bsAbs) offer unique advantages by co-targeting two antigens, enhancing tumor selectivity and internalization efficiency. Here, we report the development of a 2+2 IgG-like bispecific antibody-drug conjugate (ADC) co-targeting GP220/350 and EGFR for precise NPC therapy. The bsAb was engineered as a 2+2 IgG-like molecule. The GP220/350-binding arm was derived from a fully humanized synthetic VHH (single-domain antibody) library and a high affinity binder C2 was selected via phage display. The EGFR-binding arm was based on nimotuzumab, a low-affinity EGFR antibody chosen to minimize on-target/off-tumor toxicity. The bsAb designated as DXA038 was conjugated to a topoisomerase I inhibitor payload CPT113 via a cleavable linker, with an average drug-to-antibody ratio (DAR) of 4. Binding affinity, in vitro cytotoxicity and in vivo efficacy were assessed. DXA038-CPT113 showed superior activity both in vitro and in vivo compared to nimotuzumab-CPT113.This bispecific ADC represents a promising therapeutic strategy for EBV-positive NPC, addressing unmet needs in precision oncology.", "source_company": "Hangzhou DAC Biotechnology Co., Ltd\nHangzhou DAC Biotechnology Co., Ltd.", "source_org_type": "公司", "row_number": 137, "target_meta": "EGFR", "MOA_meta": "抗体偶联药物"}, {"drug_name": "NDV-ADC01-exatecan", "company": "NDV Therapeutics Corp.", "org_type": "公司", "target": "KRASG12D/HLA-A*11 pMHC", "modality": "ADC", "importance_level": "中", "total_score": 69.5, "institution_score": 45, "track_score": 95, "milestone_score": 65, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "该药为新型TCR-mimic ADC，靶向细胞内KRASG12D突变pMHC复合物，属于ADC热门赛道且针对难成药KRAS靶点。机构为小型未知公司得分一般，前临床模型显示强效抗瘤活性及与放疗联用免疫重塑潜力。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4466", "id": "mVXM_5wBX1NQZOEH-LK6", "source_drug_name": "NDV-ADC01-exatecan", "title": "Targeting intracellular KRASG12D/HLA-A11 pMHC with a novel TCR-mimic antibody-drug conjugate (TCRm-ADC) demonstrates potent antitumor activity in preclinical models", "abstract_text": "Antibody-drug conjugates (ADCs) targeting tumor-associated antigens (TAAs) frequently cause on-target, off-tumor side effects. TCR-mimic antibodies (TCRms) imitate the capacity of T cell receptors (TCRs) to interact with peptide-MHC complexes (pMHCs), offering a solution to target previously undruggable intracellular cancer antigens, such as KRAS mutations. Here, we screened and identified a TCRm with high specificity and affinity for the KRASG12D/HLA-A*11 pMHC complex using phage display, ELISA, and cell-based assays. We further confirmed the specificity and safety of the TCRm antibody in vitro and in vivo. Furthermore, the TCRm-ADC, NDV-ADC01-exatecan, which targets the KRASG12D/HLA-A*11 pMHC complex, mediated specific antitumor activity in vitro and in vivo without obvious toxicity in xenograft models of lung, pancreatic, and colorectal cancer. Additionally, NDV-ADC01-exatecan significantly elicited antitumor immunity and reshaped the tumor microenvironment when combined with low-dose radiotherapy in a humanized HLA-A*11/hB2M transgenic model. Together, these screening and engineering processes provide a novel therapeutic strategy to target undruggable KRASG12D-mutated cancers.", "source_company": "NDV Therapeutics Corp.", "source_org_type": "公司", "row_number": 218, "target_meta": "KRAS G12D,HLA-A11", "MOA_meta": "抗体偶联药物"}, {"drug_name": "a novel selective CDK4 inhibitor", "company": "TYK Medicines, Inc.", "org_type": "公司", "target": "CDK4", "modality": "inhibitor", "importance_level": "中", "total_score": 69.5, "institution_score": 65, "track_score": 80, "milestone_score": 60, "field_heat_score": 75, "bonus_score": 3, "brief_reason": "靶向CDK4的选择性抑制剂，旨在改善双重CDK4/6抑制剂的血液毒性，机制聚焦于避免CDK6介导的骨髓毒性。TYK Medicines为国内临床阶段biotech公司，赛道热门但仍处优化lead阶段，无临床数据，综合潜力中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3989", "id": "Z1XM_5wBX1NQZOEH-LS6", "source_drug_name": "a novel selective CDK4 inhibitor", "title": "Development of a novel selective CDK4 inhibitor for HR+/HER2- breast cancer", "abstract_text": "Targeting cell cycle-dependent kinases 4 and 6 (CDK4/6) has been proven to be a successful strategy for blocking oncogenic cell cycle progression in breast cancer cells. FDA-approved CDK4/6 inhibitors have delivered significant clinical benefits in patients with HR+/HER2- breast cancer. However, despite remarkable clinical and commercial success, dual CDK4/6 inhibitors are associated with severe on-target toxicity, leading to serious adverse events (SAEs), such as neutropenia in clinical settings. The mechanism underlying these hematologic adverse events was attributed to CDK6, rather than CDK4, for its direct mediation of myeloid cell differentiation when CDK6 expression is upregulated. To avoid CDK6 toxicity, we sought to develop selective and potent CDK4 inhibitors that in ideal cases only inhibit CDK4 activity with no impact on CDK6 or other CDKs in HR+/HER2- breast cancer cells to improve the hematologic safety of the therapeutic approach targeting the cancer cell cycle. TYK Medicines has been making continuous efforts to develop better CDK4 inhibitors with higher selectivity, potency, and lower hematologic toxicity. The candidate CDK4 inhibitor discussed in this abstract exhibits strong selectivity for CDK4 over CDK6 compared to palbociclib, confirming its identity as a selective CDK4 inhibitor rather than a dual CDK4/6 inhibitor. The compound confers a dose-dependent reduction in phosphorylated RB (Ser780) in HR+/HER2-breast cancer cell lines following a 48-hour treatment with the cells. The antiproliferative effects of the candidate compounds were evaluated via CTG cell viability assays after 5-day incubation in three cell lines: MCF7, JEKO-1, and MOLM13. Palbociclib potently inhibited MCF7/T47D cells because of its dual CDK4/6 kinase activity. In contrast, the selective CDK4 inhibitor strongly inhibited JEKO-1 cells and had no inhibitory effect on MOLM13 cells expressing high levels of CDK6. In a MCF7-xenograft mouse model, the compound significantly suppressed tumor growth in a dose-dependent manner. It also exhibited synergistic antitumor effects when combined with fulvestrant, with good tolerability evidenced by stable animal body weight throughout the study. Given the genetic diversity of HR+/HER2-breast cancer patients, targeting CDK4 may present a keystone strategy in a spectrum of combinatorial therapies. Preliminary in vitro combination studies revealed that pairing the selective CDK4 inhibitor with a CDK2 inhibitor or a PI3K inhibitor produced significant synergistic inhibitory effects on MCF7 and palbociclib-resistant MCF7 cells. Optimization of the lead compound is ongoing with the goal of identifying a preclinical candidate (PCC) for IND-enabling studies.\n# Apeng Liang and Meihua Li contributed equally to this work.\n* Correspondence authors.", "source_company": "TYK Medicines, Inc.", "source_org_type": "公司", "row_number": 902, "target_meta": "CDK4", "MOA_meta": "抑制剂"}, {"drug_name": "CAR T cell therapy", "company": "Miltenyi Biotec", "org_type": "公司", "target": "未披露", "modality": "CAR", "importance_level": "中", "total_score": 69.5, "institution_score": 75, "track_score": 85, "milestone_score": 40, "field_heat_score": 80, "bonus_score": 0, "brief_reason": "产品为CAR-T细胞疗法，聚焦B细胞恶性肿瘤以外的应用，但摘要无具体内容，未披露明确靶点或数据。Miltenyi Biotec作为细胞治疗工具与制造领域的知名公司有较强实力，CAR-T赛道整体热度高，但因缺乏preclinical强度或里程碑细节，开发进展评分较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/2903", "id": "aFXM_5wBX1NQZOEH-LS6", "source_drug_name": "CAR T cell therapy", "title": "Engineering effect CAR T cell therapy beyond B cell malignancy, lessons learned and applied", "abstract_text": "There is no abstract associated with this presentation.", "source_company": "Miltenyi Biotec", "source_org_type": "公司", "row_number": 903, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "Pioneer Antibody Library", "company": "Bio-Rad Laboratories", "org_type": "公司", "target": "未披露", "modality": "other", "importance_level": "中", "total_score": 69.5, "institution_score": 65, "track_score": 75, "milestone_score": 70, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "Pioneer Antibody Library是Bio-Rad的大型噬菌体展示Fab抗体库服务，用于快速产生治疗性抗体候选物，对难靶点如IL-6R、C5aR、CXCR4显示出高亲和力和功能性。Bio-Rad作为生命科学工具巨头而非头部biopharma公司得分中等，平台技术先进且展示临床级候选物潜力，但非具体药物且靶点未固定导致总分中位。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6479", "id": "fZ7ECZ0BZznHJdntvNYd", "source_drug_name": "Pioneer Antibody Library", "title": "Rapid lead generation with the Pioneer Antibody Discovery Platform", "abstract_text": "The Pioneer™ Antibody Discovery Platform is Bio-Rad’s biotherapeutic antibody generation service, centered around the Pioneer Antibody Library—one of the largest functional Fab libraries (225 billion unique sequences). Informed by over 18 years of phage display expertise, the library is optimized for therapeutic antibody selection. It integrates SpyDisplay, a proprietary SpyTag-based selection system, and TrailBlazer, a modular platform for rapid format assembly. We showcase data on antibody selection against IL-6R, C5aR, and CXCR4, demonstrating that the Pioneer Platform yields diverse, high-affinity, and functional leads for difficult targets. These candidates show comparable or superior performance to clinically developed or marketed antibodies across key parameters.", "source_company": "Bio-Rad Laboratories", "source_org_type": "公司", "row_number": 970, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "SCOPE", "company": "Scancell", "org_type": "公司", "target": "TRP-2 和 gp100", "modality": "DNA plasmid vaccine", "importance_level": "中", "total_score": 69.5, "institution_score": 60, "track_score": 75, "milestone_score": 80, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "SCOPE为Scancell的DNA质粒疫苗（实际产品SCIB1/iSCIB1+），靶向黑色素瘤抗原TRP-2和gp100，通过诱导T细胞响应联合检查点抑制剂治疗晚期黑色素瘤。机构为中小型biotech公司但有积极临床数据，Phase 2显示良好疗效并推进至Phase 3准备，赛道为癌症疫苗+IO组合热度较高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/12110", "id": "FVXM_5wBX1NQZOEH-LO6", "source_drug_name": "SCOPE", "title": "SCOPE, A phase 2 clinical trial with off-the-shelf DNA plasmid vaccine in first line advanced melanoma combined with check point blockade, shows good T cell responses which correlate with long progression free survival", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Scancell", "source_org_type": "公司", "row_number": 1282, "target_meta": "TRP2,gp100", "MOA_meta": "DNA疫苗"}, {"drug_name": "PMG-A9", "company": "Promedigen", "org_type": "公司", "target": "未披露", "modality": "inhibitor", "importance_level": "中", "total_score": 69, "institution_score": 65, "track_score": 80, "milestone_score": 60, "field_heat_score": 75, "bonus_score": 3, "brief_reason": "PMG-A9为口服小分子，通过恢复关键肿瘤抑制因子功能，下调Cyclin D1和c-Myc等耐药驱动因子，克服HR+乳腺癌中CDK4/6抑制剂耐药。Promedigen为韩国创新biotech，赛道针对耐药机制+肿瘤抑制因子激活具较高热度，但处于preclinical阶段，靶点具体未明确披露。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4903", "id": "n1XM_5wBX1NQZOEH-LG6", "source_drug_name": "PMG-A9", "title": "A first-in-class orally bioavailable small molecule to overcome treatment resistance in hormone receptor-positive breast cancer", "abstract_text": "CDK4/6 inhibitors combined with antiestrogens such as fulvestrant represent frontline therapy for hormone receptor-positive (HR+) breast cancer; however, therapeutic resistance inevitably emerges in a substantial subset of patients through diverse molecular mechanisms. To address this challenge, we developed PMG-A9, a novel, orally bioavailable small molecule designed to restore the function of a key tumor suppressor frequently inactivated across cancers. PMG-A9 potently downregulates major resistance drivers, including Cyclin D1 and c-Myc, in a dose-dependent manner at sub-nanomolar concentrations, while upregulating cell-cycle inhibitors and pro-apoptotic proteins, demonstrating its potential to overcome resistance to CDK4/6 inhibitors and/or fulvestrant. In preclinical HR+ breast cancer xenograft models, PMG-A9 exhibits robust single-agent antitumor activity and pronounced synergy when combined with these agents. These findings highlight tumor-suppressor reactivation as a promising and broadly applicable therapeutic strategy with the potential to address resistance not only in HR+ breast cancer but also across a wide range of tumor types.", "source_company": "Promedigen", "source_org_type": "公司", "row_number": 189, "target_meta": "not available", "MOA_meta": "抑制剂"}, {"drug_name": "multiple KRAS alleles and EGFR targeting therapy", "company": "Quanta Therapeutics", "org_type": "公司", "target": "KRAS (multiple alleles) 和 EGFR", "modality": "inhibitor", "importance_level": "中", "total_score": 69, "institution_score": 75, "track_score": 95, "milestone_score": 30, "field_heat_score": 90, "bonus_score": 0, "brief_reason": "该项目聚焦多等位KRAS直接抑制结合EGFR靶向的策略，KRAS为极热门靶点且Quanta为专注RAS的头部biotech；但本条摘要无任何具体数据或披露，处于preclinical或早期阶段无里程碑体现。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/736", "id": "Q1XM_5wBX1NQZOEH-LG5", "source_drug_name": "multiple KRAS alleles and EGFR targeting therapy", "title": "Direct targeting of multiple KRAS alleles and EGFR toward durable therapy", "abstract_text": "There is no abstract associated with this presentation.", "source_company": "Quanta Therapeutics", "source_org_type": "公司", "row_number": 356, "target_meta": "KRAS,EGFR", "MOA_meta": "抑制剂"}, {"drug_name": "ZMS-7506", "company": "Simcere Zaiming Pharmaceutical Co, Ltd.", "org_type": "公司", "target": "Cyclin A/B", "modality": "inhibitor", "importance_level": "中", "total_score": 68.5, "institution_score": 75, "track_score": 65, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "ZMS-7506为口服Cyclin A/B抑制剂，靶向细胞周期调控，针对E2F高活性肿瘤如SCLC展现选择性抗瘤活性。公司为国内头部药企先声药业肿瘤子公司，赛道为细胞周期抑制剂虽有一定关注但非最热门，数据显示体外/体内活性+良好窗口+口服生物利用度，preclinical阶段强度中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6415", "id": "GFXM_5wBX1NQZOEH-LO6", "source_drug_name": "ZMS-7506", "title": "A novel investigation of the cyclin A/B inhibitor ZMS-7506 demonstrates robust anti-tumor efficacy both in vitro and in vivo", "abstract_text": "Cyclins A and B are critical regulators of the transition from the S phase to the G2/M phase of the cell cycle. Abnormal expression and activity of these cyclins are hallmarks of cancer. Disruption of the interaction between E2F and the cyclin A2-CDK2 complex results in hyperactivation of E2F, leading to apoptosis and synthetic lethality in E2F-driven tumors. Small cell lung cancer (SCLC) cell lines commonly exhibit dysregulated E2F activity due to near-universal loss-of-function mutations in RB1 and TP53. We have developed ZMS-7506, a potent oral Cyclin A/B inhibitor, which demonstrated a median IC50 of approximately 40 nM in anti-proliferation assays using a panel of SCLC cell lines. Moreover, ZMS-7506 selectively inhibited the proliferation of ovarian cancer OVCAR3 cells, with a GI50 value below 20 nM. In the meanwhile, ZMS-7506 exhibited a GI50 greater than 10 μM in normal human embryonic lung fibroblasts (WI38), indicating a favorable therapeutic window. Mechanistically, ZMS-7506 induced G2/M cell cycle arrest and upregulated markers associated with apoptosis and mitotic arrest, including p-KNL1, p-HH3, p-PARP, and p-γ-H2AX. These findings suggest that ZMS-7506 activates the spindle assembly checkpoint (SAC), thereby inducing mitotic arrest and apoptosis. ZMS-7506 also exhibited moderate oral bioavailability in pre-clinical species such as dogs, which supported the oral administration in human. Moreover, ZMS-7506 exhibited robust antitumor efficacy as a monotherapy in the SCLC NCI-H69 xenograft mouse model. In summary, ZMS-7506 is a highly selective oral Cyclin A/B inhibitor with promising therapeutic potential as a monotherapy for cancers characterized by elevated E2F activity.", "source_company": "Simcere Zaiming Pharmaceutical Co, Ltd.", "source_org_type": "公司", "row_number": 142, "target_meta": "cyclin-A,cyclin B", "MOA_meta": "抑制剂"}, {"drug_name": "HX116", "company": "Hanx Biopharmaceuticals, Ltd", "org_type": "公司", "target": "PD-L1xVEGF", "modality": "ADC", "importance_level": "中", "total_score": 68.5, "institution_score": 65, "track_score": 90, "milestone_score": 45, "field_heat_score": 85, "bonus_score": 3, "brief_reason": "HX116为靶向PD-L1和VEGF的双特异性ADC，结合免疫检查点阻断、抗血管生成和TOPO-I毒素杀伤三种机制，具有多模态协同潜力。机构为国内创新型biotech，已有管线进入临床但非头部，赛道极热但仍处preclinical阶段无明确临床里程碑。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9445", "id": "rZ7M_5wBZznHJdnt_W3O", "source_drug_name": "HX116", "title": "A novel multi-modal PD-L1xVEGF-ADC, HX116, could be a new potent candidate treatment for pan-solid tumors", "abstract_text": "PD-L1 is an immune-checkpoint frequently over-expressed in many tumor cells as compared to normal tissues, while VEGF is an angiogenesis growth factor widely present within solid tumor microenvironment (TME). Therefore, both are also considered “tumor-associated antigen (TAA)” targetable by ADC modality, in addition to being druggable by mAbs against PD-L1-mAb (ICI) or VEGF that both are standard cancer treatments. Furthermore, multi-modal bispecific antibody (BsAb) simultaneously against PD-L1xVEGF has recently demonstrated impressive therapeutic benefit against different cancers in clinics, superior to single modal treatments or their combo treatments. It is therefore reasonable to hypothesize that a PD-L1xVEGF BsAb-ADC, HX116, with additional modalities of TOPO-I inhibitor, could become an even more powerful next-generation treatment of cancers than the naked BsAb. We thus tested HX116 for its anti-tumor activity in preclinical settings, in parallel to naked antibodies of HX116-and those against VEGF and PD-L1, respectively, so enabling assessing the roles of each modality of HX116. First, although the naked HX116 BsAb specifically binds to several PD-L1+ tumor cells with high affinity, it exhibited poor internalization in PD-L1+ cells. As a result, HX116 showed poor cytotoxicity in these cells as compared to SGN-PDL1V, a PD-L1-MMAE-ADC that is internalized efficiently. In contrast, HX116 demonstrated as robust cytotoxicity as much as, if not more, as SGN-PDL1V in these two PD-L1+ 3D-tumor organoids in vitro, contrasting to the very poor cytotoxicity induction seen in the 2D-cell culture. It also showed robust anti-tumor activity in multiple PD-L1+ human tumor xenograft models in vivo, including the ones with poor in vitro cytoxicity induction, and also superior to the naked BsAb, confirming the contributions of the additive ADC modality. Secondly, the parallel VEGF-mAb and naked HX116 BsAb in the same xenografts also demonstrated equal and robust tumor responses, suggesting the contribution of anti-angiogenesis modality. Thirdly, the pharmacology evaluation in human PBMC humanized xenograft model is currently ongoing, its superior activity over naked HX116 BsAb and PD-L1mAb would confirm its ICI contribution to the anti-tumor activity. Considering that the clinical dose for the similar PD-L1xVEGF BsAb needs to be high as 20~30 mg/kg to fully deploy their immune-checkpoint and anti-angiogenesis modalities in human, we have specifically selected a payload with moderate-potency as well as an optimal DAR value that will be tolerated in such high clinical doses. The high safety and tolerability of HX116 will also be confirmed in NHP model. If all are confirmed, HX116 would become a powerful new candidate for future cancer treatment.\nReference: A living biobank of matched pairs of patient-derived xenografts and organoids for cancer pharmacology. PLoS One, 2023. 18(1): p. e0279821.", "source_company": "Hanx Biopharmaceuticals, Ltd", "source_org_type": "公司", "row_number": 164, "target_meta": "not available", "MOA_meta": "抗体偶联药物"}, {"drug_name": "68Ga-AVA-ERL", "company": "Avammune Therapeutics", "org_type": "公司", "target": "ENPP3", "modality": "RLT imaging agent", "importance_level": "中", "total_score": 68.5, "institution_score": 65, "track_score": 85, "milestone_score": 55, "field_heat_score": 75, "bonus_score": 3, "brief_reason": "靶点ENPP3为实体瘤过表达的新兴靶点，药物为first-in-class小分子68Ga标记的放射性配体成像剂，可作为ENPP3靶向放射治疗基础。Avammune为有Series A融资的国外新兴biotech，赛道RLT+新靶点热度高，但仍处早期preclinical阶段，综合潜力中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3902", "id": "lFXM_5wBX1NQZOEH-LK6", "source_drug_name": "68Ga-AVA-ERL", "title": "Development of a first-in-class ENPP3-targeted radioligand for liver and renal cancer imaging", "abstract_text": "Background: Ectonucleotide pyrophosphatase/phosphodiesterase 3 (ENPP3) represents a promising target for cancer therapy due to its overexpression in various solid tumors, specifically hepatocellular carcinoma, renal cell carcinoma, prostate cancer, colorectal carcinoma and ovarian cancer. Several high affinity bispecific antibodies and ADCs targeting ENPP3 are currently in clinical development thereby demonstrating the clinical translatability of this target. Radioligand therapy (RLT) has demonstrated tremendous potential to improve survival in cancer patients with limited or ineffective treatment options. Herein, we report the discovery of a first-in-class small molecule radioligand (68Ga-AVA-ERL) for high ENPP3 tumors imaging that can form the basis for further development of ENPP3-targeted radiotherapeutics.\nMethods: ENPP3 ligands generated from in-house libraries were conjugated with dye or DOTA (followed by radiolabeling with 68Ga). Target engagement (affinity and specificity) studies with Cy5 labelled AVA-ERL compounds were carried out to confirm in vitro binding using both high (HepG2) and low (MDA-MB-231) ENPP3-expressing cell lines. In vivo fluorescence imaging (IVIS) and ex vivo tissue analysis of Cy5 labelled AVA-ERL compounds was carried out in nude mice bearing HepG2 tumor to confirm target specificity. Imaging studies with 68Ga-AVA-ERL compounds was further carried out in HepG2 tumors.\nResults: We have developed a library of AVA-ERL compounds (dye and radiolabelled) targeting ENPP3. Upon screening this library for in vitro and in vivo binding assay, pharmacokinetic profiling and biodistribution studies, we identified the lead ligands suitable for 68Ga based imaging studies. Our novel first-in-class ENPP3 targeted RLT has demonstrated efficient target engagement, high tumor uptake and a favourable biodistribution profile.\nConclusions: To our knowledge, the compounds described here are the first disclosure of small molecule ligands targeting ENPP3 for radiotheranostics. Dye and radiolabelled AVA-ERL-compounds have demonstrated a favourable pharmacokinetic profile and efficient target engagement. Our findings demonstrate the potential of a first-in-class ENPP3 targeted radioligand for imaging that can form the basis for the development of potentially effective radioligand therapeutics for HCC.", "source_company": "Avammune Therapeutics", "source_org_type": "公司", "row_number": 217, "target_meta": "ENPP3", "MOA_meta": "其他"}, {"drug_name": "CHK1 inhibitor ADC", "company": "Cancentus Pharma", "org_type": "公司", "target": "HER2", "modality": "ADC", "importance_level": "中", "total_score": 68.5, "institution_score": 45, "track_score": 90, "milestone_score": 70, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "该ADC以CHK1抑制剂作为新型payload，靶向HER2，旨在克服现有TOP1类ADC的毒性和耐药局限，创新payload类别具有差异化潜力。Cancentus为早期瑞士biotech，机构分偏低，但ADC+新型DNA损伤靶向payload赛道热度高，体外/体内数据支持有效性和安全性，综合潜力中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5384", "id": "blXM_5wBX1NQZOEH-LK6", "source_drug_name": "CHK1 inhibitor ADC", "title": "First-in-class CHK1 inhibitor antibody-drug conjugate overcomes limitations of current ADC payloads and provides a new option for HER2-positive and TOP1 inhibitor-resistant tumors", "abstract_text": "Background:\nCurrent ADCs rely almost exclusively on two payload classes -TOP1 poisons and microtubule inhibitors- leading to significant toxicity, frequent dose interruptions and reductions, and limited options once resistance develops. To address these limitations, we developed a first-in-class ADC incorporating a novel payload class: a CHK1 inhibitor (CHK1i). The novel payload exploits the presence of DNA replication stress in cancer, leading to greater selectivity.\nMethods:\nTrastuzumab variants containing engineered cysteines were generated to enable site-specific conjugation. A proprietary cleavable linker was synthesized and conjugated to the CHK1i payload. The resulting ADC was evaluated for HER2-dependent activity in vitro and tested in vivo in a HER2-positive breast cancer xenograft model (HCC1569).\nResults:\nAs a small molecule, the CHK1i was about 50-fold less toxic to normal cells than a TOP1 poison (deruxtecan) while maintaining comparable potency in cancer cell lines. When bound to the ADC linker, the CHK1i was not toxic to cells, in contrast to the deruxtecan-linker, which retains toxicity.\nTrastuzumab with five engineered cysteines, combined with a novel cleavable linker and a CHK1i as payload, enabled enhanced ADC potency and selective killing of HER2-positive cancer cells. In vivo testing of the ADC, administered intravenously once per week for five consecutive weeks, demonstrated antitumor efficacy at 10 mg/kg in the HCC1569 xenograft model. Mice were monitored for three weeks after treatment completion, and tumor growth inhibition was still observed. No body weight loss or obvious signs of toxicity were detected.\nConclusions:\nThis first-in-class CHK1i ADC expands payload diversity, aims to address resistance to existing ADCs and reduce nonspecific toxicity, offering the potential for a wider therapeutic window.", "source_company": "Cancentus Pharma", "source_org_type": "公司", "row_number": 558, "target_meta": "HER2", "MOA_meta": "抗体偶联药物"}, {"drug_name": "a novel 2+2 IgG-like bispecific antibody-drug conjugate targeting both CDH17 and GUCY2C", "company": "Hangzhou DAC Biotechnology Co., Ltd", "org_type": "公司", "target": "CDH17 and GUCY2C", "modality": "ADC", "importance_level": "中", "total_score": 68.5, "institution_score": 65, "track_score": 90, "milestone_score": 45, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "该双特异性ADC同时靶向CDH17和GUCY2C两个GI癌相关抗原，采用双payload设计，针对异质性肿瘤具有潜在优势。Hangzhou DAC为专注ADC的国内biotech公司，非头部但有一定平台积累，赛道热门但仍处preclinical阶段。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6473", "id": "L1XM_5wBX1NQZOEH-LO6", "source_drug_name": "a novel 2+2 IgG-like bispecific antibody-drug conjugate targeting both CDH17 and GUCY2C", "title": "A novel 2+2 IgG-like bispecific antibody-drug conjugate with dual payloads for targeted therapy of heterogeneous gastrointestinal cancers", "abstract_text": "Gastrointestinal (GI) cancers, including colorectal, gastric, and pancreatic cancers, remain a leading cause of cancer-related mortality globally due to their high incidence, aggressive progression, and profound intratumoral heterogeneity. This heterogeneity often leads to treatment resistance and limits the efficacy of monotherapies. Cadherin-17 (CDH17) and Guanylate Cyclase C (GUCY2C) are two promising tumor-associated antigens (TAAs) that are broadly and specifically overexpressed in various GI cancers, making them ideal targets for dual-specific therapy. Bispecific antibodies (bsAbs) offer a strategic advantage by co-targeting two distinct antigens, potentially enhancing tumor selectivity, overcoming heterogeneity, and improving therapeutic outcomes. Here, we report the development of a novel 2+2 IgG-like bispecific antibody-drug conjugate (ADC) targeting both CDH17 and GUCY2C, engineered to address the unmet needs in GI cancer treatment. The bispecific antibody was constructed as a 2+2 IgG-like molecule. The CDH17-binding arm was derived from a humanized single-domain antibody (VHH) isolated from an immunized alpaca library, selected for high affinity and specificity. The GUCY2C-binding arm was a fully human IgG1 kappa antibody identified through biopanning of a human phage display library. The resulting bsAb was site-specifically conjugated to a proprietary dual-payload linker-drug system from Hangzhou DAC, consisting of a potent antimetabolite drug and a topoisomerase I inhibitor. The bsAb exhibited high-affinity binding to both CDH17 and GUCY2C (KD values in the low nanomolar range) and demonstrated dual-specific binding to cells expressing either or both antigens. This ADC agent also demonstrated potent cytotoxicity against both single and dual antigen-expressing tumor cells. The promising preclinical efficacy profile of this ADC support its potential as a targeted therapy for patients with advanced GI cancers, offering a new strategy to overcome treatment resistance and improve clinical outcomes.", "source_company": "Hangzhou DAC Biotechnology Co., Ltd\nHangzhou DAC Biotechnology Co., Ltd.", "source_org_type": "公司", "row_number": 684, "target_meta": "CDH17,GUCY2C", "MOA_meta": "抗体偶联药物"}, {"drug_name": "linear mRNA vaccine", "company": "Charles River Laboratories", "org_type": "公司", "target": "未披露", "modality": "mRNA", "importance_level": "中", "total_score": 68.5, "institution_score": 65, "track_score": 85, "milestone_score": 55, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "线性mRNA疫苗针对肿瘤相关抗原或新生抗原，展示出比肽疫苗更强的T细胞免疫原性和杀伤功能；Charles River作为全球领先CRO在preclinical平台有较强支持，但非药企开发主体，摘要为工具性benchmark研究而非具体候选推进，赛道热度高但开发阶段早期。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3639", "id": "A57M_5wBZznHJdnt_W7O", "source_drug_name": "linear mRNA vaccine", "title": "Next-generation RNA vaccine modalities enable high-fidelity antigen discovery and T-cell immunogenicity screening", "abstract_text": "RNA-based cancer vaccines provide exceptional flexibility for encoding tumour-associated antigens (TAAs) or patient-specific neoantigens and recent clinical data show promising efficacy over traditional approaches, yet comparative functional data across RNA formats remain limited. We developed an integrated evaluation workflow to benchmark linear mRNA, circular RNA (circRNA), self-amplifying RNA (saRNA), and 27-mer peptide vaccines for their ability to drive antigen expression and prime functional antigen-specific T-cell responses.   Using GFP reporter constructs, expression levels and persistence were assessed across selected RNA formats in primary antigen-presenting cells. Linear mRNA and circRNA robustly produced higher and more durable antigen expression than peptide pulsing, consistent with emerging insights into RNA vaccine potency. Vaccine candidates were subsequently screened using an antigen-specific T-cell expansion workflow, which expands rare tumour-reactive CD8+ T cells via a mature dendritic cell (DC) co-culture system. This platform addresses challenges of low precursor frequency and HLA diversity, enabling de novo priming of T cells against TAAs such as MART-1 or unique neoantigens. In the majority of donors, RNA-encoded antigens elicited stronger T-cell responses than 27-mer peptides, reflected by greater expansion of antigen-specific CD8+ T cells and increased IFNγ release following restimulation. Functional killing was confirmed using peptide-loaded tumour targets and tumour cell lines endogenously expressing relevant-antigen. RNA-encoded antigens produced T cells with higher cytotoxic potential, evidenced by enhanced tumour apoptosis in killing assays. Crucially, the strongest response seen was with a circRNA neoantigen vaccine candidate relative to the same neoantigen encoded in linear mRNA or peptide formats. To support personalised vaccine programs, putative neoantigens were first validated using TAP-deficient MHC-loading assays to confirm direct presentation, then screened in the DC-T-cell co-cultures to generate donor-resolved immunogenicity hierarchies. This enabled rapid identification of high-value epitopes suitable for inclusion in bespoke mRNA or circRNA vaccine constructs. Collectively, these data demonstrate that RNA vaccine modalities can outperform peptide-based vaccination in generating functional tumour-reactive T cells. The integrated platform provides a modality-agnostic, human-relevant workflow spanning antigen selection, RNA vaccine characterisation, and comprehensive functional T-cell assessment, supporting rapid advancement of next-generation cancer vaccine pipelines.", "source_company": "Charles River Laboratories", "source_org_type": "公司", "row_number": 1132, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "HLA-G-targeted ADC", "company": "IMBiologics Corp.", "org_type": "公司", "target": "HLA-G", "modality": "ADC", "importance_level": "中", "total_score": 68.5, "institution_score": 65, "track_score": 85, "milestone_score": 50, "field_heat_score": 75, "bonus_score": 3, "brief_reason": "靶向HLA-G的ADC，HLA-G作为免疫抑制检查点在多种实体瘤中异常表达，具有免疫逃逸作用；IMBiologics为韩国新兴biotech公司（非头部），ADC赛道热门但HLA-G靶点新兴热度中等，处于preclinical阶段有异种瘤模型完全缓解数据但无临床进展。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5693", "id": "Pp7M_5wBZznHJdnt_W7O", "source_drug_name": "HLA-G-targeted ADC", "title": "Exploring the anti-tumor potential of HLA-G-targeted therapeutics through diverse preclinical approaches", "abstract_text": "HLA-G, a non-classical MHC class I molecule with potent immunosuppressive properties, is aberrantly expressed in various solid tumors and plays a critical role in immune evasion. This immune suppression is primarily mediated through its interaction with inhibitory receptors such as ILT-2 on immune cells, which dampens anti-tumor responses and facilitates tumor progression. As such, HLA-G functions as an immune checkpoint molecule, making it a promising target for cancer immunotherapy. Monoclonal antibodies and CAR-T therapies targeting HLA-G have been previously explored; however, further optimization of therapeutic formats, incorporation of novel modalities such as antibody-drug conjugates (ADCs) and multi-specific antibodies, and preclinical validation are needed to advance their clinical potential. In this study, we present a preclinical evaluation of HLA-G-targeting biologics, including ADCs and bispecific antibodies, with emphasis on pharmacokinetics, efficacy, and biomarker-guided tumor selectivity. Notably, in a choriocarcinoma xenograft model, one complete response was observed following ADC monotherapy, suggesting the therapeutic potential of HLA-G-targeted ADCs in specific tumor contexts. To further assess clinical relevance, MiniPDX platforms derived from patient tumors were employed for target validation and biomarker correlation. These studies indicate HLA-G expression may serve as a predictive marker for therapeutic response and revealed differential efficacy across tumor types. In parallel, bispecific antibodies targeting HLA-G and co-expressed tumor antigens were evaluated for binding affinity and cytotoxicity. Bispecific formats demonstrated enhanced tumor cell engagement and potent anti-tumor activity, suggesting their utility in overcoming antigen heterogeneity and resistance mechanisms. Collectively, these findings provide preclinical evidence supporting the development of HLA-G-targeting therapeutics using diverse modalities. ADCs are particularly appealing as they can enhance potency through cytotoxic payloads while minimizing off-target toxicity due to the tumor-specific antigen nature of HLA-G. In addition, bispecific antibodies may offer further tumor selectivity and augment immune activation. This study presents additional efficacy data from in vivo xenograft and MiniPDX models, contributing to the ongoing preclinical evaluation of HLA-G-targeting strategies. Importantly, HLA-G has emerged as a potential therapeutic target capable of delivering robust efficacy through diverse therapeutic modalities and may serve as a predictive biomarker. These findings underscore the potential of HLA-G-targeted therapeutics, particularly ADCs and bispecific formats, as investigational treatment options for cancers with limited effective therapies, such as ovarian cancer.", "source_company": "IMBiologics Corp.", "source_org_type": "公司", "row_number": 1166, "target_meta": "HLA-G", "MOA_meta": "抗体偶联药物"}, {"drug_name": "MGT-1143", "company": "Marigold Therapeutics, Inc.", "org_type": "公司", "target": "CDH17", "modality": "ADC", "importance_level": "中", "total_score": 68.5, "institution_score": 55, "track_score": 85, "milestone_score": 65, "field_heat_score": 80, "bonus_score": 2, "brief_reason": "MGT-1143为靶向CDH17的Exatecan-based ADC，针对泛胃肠道癌症，CDH17在GI癌中高表达且与预后差相关。机构为2024年底新成立的ADC专注新兴biotech，得分中等；ADC+新兴靶点CDH17（近年多款进入临床，热度上升）赛道较热，前临床数据扎实（体外/体内高效，IND-enabling中），综合潜力中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4050", "id": "iVXM_5wBX1NQZOEH-LO6", "source_drug_name": "MGT-1143", "title": "MGT-1143, a novel CDH17-targeting ADC for gastrointestinal cancers", "abstract_text": "Background: Pan-gastrointestinal cancers represent a heterogeneous group of malignancies arising from the gastrointestinal tract, including esophageal, gastric, pancreatic, and colorectal cancers, which collectively contribute to a major global cancer burden and mortality. Cadherin-17 (CDH17), a Ca²⁺-dependent adhesion molecule, is overexpressed across multiple GI cancers and has been associated with poor prognosis. Here, we report the development and preclinical evaluation of MGT-1143, a novel Exatecan-based ADC that integrates a fully humanized anti-CDH17 monoclonal antibody (mAb) with Marigold’s proprietary linker platform. MGT-1143 is currently undergoing IND-enabling studies.\nMethods: The preclinical activity of MGT-1143 was assessed through a series of in vitro and in vivo studies to characterize its pharmacological and safety profiles. Binding affinity, cross-species reactivity, and target specificity of MGT-1143 were evaluated using ELISA and flow cytometry. Antibody internalization was determined by flow cytometry, while cytotoxicity was assessed using the CellTiter-Glo luminescent viability assay. In vivo anti-tumor efficacy was evaluated in CDH17-positive cell line-derived xenograft (CDX) models.\nResults: The MGT-1143 antibody exhibited high target specificity with no detectable cross-reactivity toward other cadherin family members. MGT-1143 demonstrated strong binding affinity and rapid internalization in CDH17-expressing cells, resulting in potent cytotoxicity across multiple CDH17-positive cell lines. Furthermore, MGT-1143 induced robust and dose-dependent anti-tumor activity in xenograft mouse models expressing varying levels of CDH17, confirming its target-dependent efficacy.\nConclusions: Collectively, the preclinical data support the continued development of MGT-1143 as a promising therapeutic candidate for the treatment of CDH17-positive gastrointestinal cancers. Ongoing IND-enabling studies will further define its safety and translational potential.", "source_company": "Marigold Therapeutics, Inc.", "source_org_type": "公司", "row_number": 1251, "target_meta": "CDH17", "MOA_meta": "抗体偶联药物"}, {"drug_name": "Artificial Intelligence-designed peptide PROTAC", "company": "Harvard Medical School/MIT", "org_type": "大学", "target": "DHHC3", "modality": "PROTAC", "importance_level": "中", "total_score": 68.3, "institution_score": 45, "track_score": 92, "milestone_score": 75, "field_heat_score": 85, "bonus_score": 6, "brief_reason": "AI设计的肽类PROTAC靶向DHHC3调控PD-L1棕榈酰化，显著抑制TNBC肿瘤生长并优于现有PD-L1抑制剂，展现出靶向蛋白降解新机制潜力。机构为顶尖学术单位得分中等，PROTAC+AI+免疫治疗相关热门赛道与较强的preclinical数据推动总分处于中上水平。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3541", "id": "TVXM_5wBX1NQZOEH-LG5", "source_drug_name": "Artificial Intelligence-designed peptide PROTAC", "title": "Artificial intelligence-designed peptide PROTACs suppress TNBC by regulating PD-L1 palmitoylation", "abstract_text": "Background: Triple-negative breast cancer (TNBC) responds poorly to immune checkpoint blockade (ICB), partly due to sustained PD-L1 expression on tumor cells. PD-L1 palmitoylation enhances its membrane stability and limits internalization, contributing to immune evasion. Modulating PD-L1 palmitoylation therefore represents an attractive strategy to overcome ICB resistance. Here, we developed an Artificial Intelligence-designed peptide PROTAC platform to regulate PD-L1 palmitoylation and restore anti-tumor immunity in TNBC.\nMethods: Using an Artificial Intelligence-guided structural peptide-design workflow, we generated membrane-permeable peptide PROTACs composed of: (1) a high-affinity DHHC3-binding peptide, (2) a cell-penetrating peptide module, and (3) a small-molecule E3 ligase ligand. TNBC models (MDA-MB-231 and 4T1) were used to evaluate the effects of these degraders on DHHC3 levels, PD-L1 palmitoylation, PD-L1 expression, T-cell activation, apoptosis, and in vivo antitumor efficacy.\nResults: The lead Artificial Intelligence-designed degrader efficiently reduced DHHC3, leading to substantial suppression of PD-L1 palmitoylation and marked downregulation of PD-L1 protein at nanomolar concentrations. In vitro, the degrader significantly enhanced T-cell-mediated cytotoxicity and increased IFN-γ and TNF-α secretion. In ICB-resistant 4T1 TNBC models, systemic administration of the peptide PROTAC resulted in strong tumor growth inhibition, outperforming PD-L1 monoclonal antibodies and small-molecule PD-L1 inhibitors. Tumor tissues showed increased apoptosis, reduced Ki67, robust loss of PD-L1, and no detectable systemic toxicity.\nConclusions: Artificial Intelligence-designed peptide PROTACs effectively suppress TNBC by regulating PD-L1 palmitoylation. This strategy expands the therapeutic potential of targeted protein degradation and provides a promising approach for highly aggressive and treatment-refractory TNBC.", "source_company": "Harvard Medical School/MIT", "source_org_type": "大学", "row_number": 363, "target_meta": "ZDHHC3", "MOA_meta": "PROTAC"}, {"drug_name": "the most advanced CAR", "company": "Rubik Therapeutics", "org_type": "公司", "target": "未披露", "modality": "CAR", "importance_level": "中", "total_score": 68, "institution_score": 55, "track_score": 85, "milestone_score": 65, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "靶点未披露，但基于Oncolinkage平台发现的高度肿瘤选择性表面靶点，开发针对实体瘤的CAR-T；Rubik为专注实体瘤选择性靶点的早期Biotech公司，赛道热门且有primary T细胞功能验证及剂量依赖细胞毒性数据，整体潜力中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4368", "id": "-lXM_5wBX1NQZOEH-LC5", "source_drug_name": "the most advanced CAR", "title": "Discovery and characterization of CARs against novel, highly selective solid tumor targets identified using the Oncolinkage platform", "abstract_text": "CAR T cell therapy has demonstrated remarkable efficacy in treating hematologic malignancies. However, these therapies have been largely unsuccessful in solid tumors, which account for approximately 90% of cancer diagnoses. A critical obstacle to developing CAR T cell therapies for solid tumors is the lack of surface-expressed targets that are selectively present on tumors and not healthy tissues. Identification of tumor-restricted targets is essential to avoid on-target, off-tumor toxicity, which has proven therapeutically limiting for several CAR T therapies, including anti-PSMA and MSLN CARs. To address this challenge, we developed Oncolinkage, a computational platform to discover novel, selectively expressed surface targets whose upregulation is linked to an inciting oncogenic event through the non-specific nature of genomic mutation. As these events drive tumor formation, oncolinked targets are under positive selection, resulting in uniform expression and resistance to loss, making them ideal CAR targets. We first selected a set of ten surface targets that exhibited oncolinked properties--restricted expression in normal tissues, but dysregulated expression in tumors-and identified antibodies that bound cells for 9/10 targets examined. Binding was confirmed by CRISPR/Cas9 knockout of the gene of interest and assessed by flow cytometry. Next, 4-1BB/CD3z CARs were generated for each target using the VH/VL regions of the identified antibodies for scFv generation. After lentiviral transduction of CAR constructs into Jurkat E6.1 cells, active CARs were identified for multiple targets by assessing antigen-dependent CD69 upregulation in overnight co-culture experiments with target-expressing cell lines. The most advanced CAR binds a surface protein whose cancer-specific amplification is observed in subsets of multiple solid tumors, including lung and prostate cancers. This CAR was advanced into primary donor T cells for functional validation. Cytotoxicity was assessed against cell lines exhibiting varying antigen densities of the target protein to demonstrate anti-tumor efficacy at expression levels comparable to primary human tumors. Together, this study highlights the potential of the Oncolinkage platform to efficiently identify and validate multiple novel CAR targets and demonstrates pre-clinical efficacy of solid tumor-directed CARs based on this platform.", "source_company": "Rubik Therapeutics", "source_org_type": "公司", "row_number": 3, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "Mesothelin-targeting CAR-T cells", "company": "Crown Bioscience, Inc.", "org_type": "公司", "target": "Mesothelin", "modality": "CAR", "importance_level": "中", "total_score": 68, "institution_score": 55, "track_score": 85, "milestone_score": 65, "field_heat_score": 80, "bonus_score": 0, "brief_reason": "靶向Mesothelin的CAR-T细胞，在含纤维母细胞的复杂TME类器官共培养模型中显示剂量依赖性强效杀伤（>90%体积减少），平台用于候选物筛选和机制洞察。Crown Bioscience作为CRO机构评分中等，CAR赛道和细胞治疗领域热度高，但仅preclinical评估且非自研管线导致综合重要性为中。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5215", "id": "NlXM_5wBX1NQZOEH-LK6", "source_drug_name": "Mesothelin-targeting CAR-T cells", "title": "Comprehensive preclinical evaluation of CAR-T cell therapeutics in organoid-fibroblast co-cultures", "abstract_text": "Introduction: Preclinical assessment of CAR-T cell therapies requires models that recapitulate the complex tumor microenvironment (TME), but conventional 2D cultures fail to model stromal barriers. Patient-derived (xenograft) organoids (PDOs/PDXOs) offer superior clinical relevance, but analyzing 3D immune-tumor-stromal interactions is challenging with bulk assays like LDH release. High-Content Imaging (HCI) overcomes these limitations, enabling high-throughput, multi-parametric quantification of immune infiltration and cytotoxicity. We utilized an HCI-based organoid co-culture platform to evaluate CAR-T therapies in both standard and complex, fibroblast-containing TME models.\nMethods: Organoids were co-cultured with PBMCs or engineered CAR-T cells in a 384-well format suitable for automation. HCI analysis allowed quantification of different cell populations and several key readouts, including organoid volume (via actin and DAPI staining), fibroblast network branching (via Cy5 staining) at 96h, and T-cell infiltration at 48h. For a head-to-head lead selection study, seven distinct Claudin18.2-targeting CAR-T candidates were screened against three pancreatic organoid models to comparatively assess their cytotoxic potential. To model a complex TME, ovarian model OV9522B was co-cultured with Normal Human Lung Fibroblasts (NHLF). Triple co-cultures were treated with Mesothelin (MSLN)-targeting CAR-T cells at various Effector-to-Target (E:T) ratios (20:1, 10:1, 5:1).\nResults: Baseline Graft-versus-Tumor (GvT) effects were established by co-culturing PBMCs from four healthy donors with four organoid models (LU9906B, CR5082B, CR20155B, PA20077B) revealing variable donor- and model-dependent cytotoxicity (5%-20%). The platform enabled comparison and ranking of seven Claudin18.2-targeting CAR-T candidates against three models. This screen revealed a wide range of killing potency: the most potent CAR-T induced >80% volume reduction in the most sensitive pancreatic model, while the weakest CAR-T showed ~10% reduction in a poor responsive model. Finally, in the triple co-culture model, MSLN-targeting CAR-T cells induced potent, dose-dependent killing of OV9522B organoids (high MSLN expression). Despite a stromal network, a significant reduction (>90%) in organoid volume and visualized CAR-T engagement were observed, demonstrating fibroblasts did not affect cytotoxic activity in this case.\nConclusion: Integration of HCI with organoid co-cultures provides a comprehensive, scalable, and clinically relevant platform for evaluating cell therapies. Visualizing and quantifying key parameters like targeted killing in presence of stromal components is a critical advantage and enables confident ranking of therapeutic candidates and provides mechanistic insights, de-risking and accelerating clinical development for next-generation cell therapies.", "source_company": "Crown Bioscience, Inc.", "source_org_type": "公司", "row_number": 29, "target_meta": "MSLN", "MOA_meta": "其他"}, {"drug_name": "chimeric antigen receptor T-cell therapy", "company": "Mayo Clinic College of Medicine and Science", "org_type": "大学", "target": "未披露", "modality": "CAR", "importance_level": "中", "total_score": 68, "institution_score": 65, "track_score": 90, "milestone_score": 45, "field_heat_score": 85, "bonus_score": 0, "brief_reason": "该研究针对CAR-T细胞疗法在侵袭性淋巴瘤中的线粒体转录组特征，与临床应答相关，但未披露具体新靶点或药物，仅为机制探索性分析。机构为知名大学医院，CAR-T赛道热度高，但摘要为回顾性单细胞分析，无明确药物开发里程碑。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10015", "id": "oVXM_5wBX1NQZOEH-LG6", "source_drug_name": "chimeric antigen receptor T-cell therapy", "title": "Mitochondrial transcriptome profiles associated with clinical responses to CAR-T therapy in aggressive lymphoma", "abstract_text": "Introduction: Therapeutic outcomes in B-cell non-Hodgkin’s lymphoma (B-NHL) have substantially improved with the introduction of chimeric antigen receptor T-cell (CAR-T) therapy. Yet, persistent immune dysfunction and underlying metabolic dysregulation remain major obstacles to achieving durable clinical responses in B-NHL. We hypothesize that mitochondrial pathways play a critical role in mediating anti-tumor immunity during CAR-T therapy.\nMethods: Peripheral blood mononuclear cells were collected from healthy controls (CNTRL, n=5) and patients with advanced stage lymphoma (LYM) who received FDA approved CAR-T (n=32). Samples were collected before lymphodepletion (BL), at peak CAR-T expansion (PK) and one-month post-infusion (M1). Single-cell RNA sequencing was used to interrogate differential mitochondrial gene expression. Samples were obtained from LYM patients with complete remission for >6 months (CR), primary refractory (PD1), or relapsed (PD2) disease.\nResults: Compared to CNTRLs, LYM patients exhibited reduced expression of cytochrome c oxidase. At BL, CR patients demonstrated broader mitochondrial differential gene expression across all T-cell subsets relative to PD1 and PD2 and showed higher expression of MT-ATP-6, MT-ATP-8, and MT-CO3. Following CAR-T infusion, global mitochondrial gene expression increased across patients corresponding with expansion of CD8 effector T cells (Tem tumor circulating) and activated peripheral memory T cells (Tpm). Certain mitochondrial genes, such as MT-CO1, were durably expressed across LYM patients at BL, PK, and M1 in peripheral and central memory T cells (Tpm, Tcm). At PK, cytochrome c oxidase and ATP synthase genes were upregulated in CR Tpm and Tcm. At M1, MT-ATP-6, MT-ATP-8, MT-CO3 were significantly upregulated in CD8 memory precursor effector T-cells (MPECs) of CR patients compared to both PD1 and PD2. While CR and PD2 patients appeared clinically responsive at M1, CR samples maintained significantly higher MT-ATP-8 expression across T cell subsets (CD8 MPECS, Tpm, Tcm) compared to PD2 (p values 0.008; <0.0001; <0.0001).\nConclusions: We report a temporal shift in immunometabolism with CAR-T therapy in LYM. Clinical responders exhibited sustained mitochondrial activity characterized by persistent expression of ATP synthase in CD8 MPECs and cytochrome c oxidase in Tpm and Tcm. In sum, mitochondrial programming may distinguish effective versus dysfunctional T cells and identify targets for therapeutic development.", "source_company": "Mayo Clinic College of Medicine and Science", "source_org_type": "大学", "row_number": 422, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "αTIGIT-guided IL-15 mimetics", "company": "Changping Laboratory", "org_type": "研究机构", "target": "TIGIT", "modality": "bispecific antibody", "importance_level": "中", "total_score": 68, "institution_score": 55, "track_score": 85, "milestone_score": 60, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "药物为TIGIT靶向的IL-15拟态双抗，通过精准T细胞靶向实现强效低毒抗肿瘤免疫，机制创新解决细胞因子单药活性不足问题。机构为国内新型国家级研究机构非头部药企得较低分，赛道热门（双抗+细胞因子）且有体内强效肿瘤控制加分，但仍处preclinical阶段无临床里程碑。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9638", "id": "YFXM_5wBX1NQZOEH-LS6", "source_drug_name": "αTIGIT-guided IL-15 mimetics", "title": "αTIGIT-guided IL-15 mimetics enable potent and safe antitumor immunity", "abstract_text": "Cytokines are powerful modulators of antitumor immunity, but their clinical use is constrained by structural instability and systemic toxicity. Although antibody-based cytokine mimetics have recently emerged to activate immune cells in vitro, their therapeutic activity in vivo remains uncertain. Here, using interleukin-15 (IL-15) as a model, we engineered bispecific antibody-based IL-15 mimetics guided by AlphaFold3-assisted structural modeling. Comparative screening of multiple formats identified tandem IL-15 mimetics with strong in vitro bioactivity, but unexpectedly showed minimal antitumor activity in vivo. Strikingly, incorporating TIGIT-directed targeting transformed these mimetics into potent and nontoxic cytokine agonists, resulting in strong tumor control associated with enhanced effector activation and expansion of intratumoral CD8⁺ stem-like T cells. These findings indicate that current cytokine mimetics have limited activity when used alone and require precise T-cell targeting to achieve therapeutic potency. Our study highlights a strategy to use cytokine mimetics to overcome the mismatch between immune checkpoint blockade and low-potency cis-targeted cytokines, offering a path toward safer and more effective cytokine immunotherapy.", "source_company": "Changping Laboratory", "source_org_type": "研究机构", "row_number": 896, "target_meta": "TIGIT", "MOA_meta": "双特异性抗体"}, {"drug_name": "anti-PD-1", "company": "RoukenBio", "org_type": "公司", "target": "PD-1", "modality": "inhibitor", "importance_level": "中", "total_score": 68, "institution_score": 65, "track_score": 85, "milestone_score": 45, "field_heat_score": 80, "bonus_score": 0, "brief_reason": "anti-PD-1为经典免疫检查点抑制剂，靶向PD-1，属于成熟热门赛道；RoukenBio作为专注免疫学的中小型CRO公司，非药企自身研发，摘要仅展示体外模型评估anti-PD-1部分逆转T细胞耗竭，无药物自身开发里程碑，整体重要性中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4568", "id": "Q57M_5wBZznHJdnt_W3O", "source_drug_name": "anti-PD-1", "title": "In vitro antigen-specific T cell exhaustion model for immunomodulators evaluation", "abstract_text": "The identification of novel molecular mechanisms underlying exhausted CD8⁺ T cells (TEX) represents a critical objective in advancing immunotherapeutic strategies for cancer and other diseases. Nevertheless, high-throughput analysis of in vitro TEX remains challenging. We developed a human in vitro model of CD8⁺ T cell exhaustion using antigen-specific or TCR-transgenic T cells subjected to chronic antigen stimulation. Repeated exposure to cognate peptide antigens induced hallmark exhaustion phenotypes, including co-expression of inhibitory receptors (PD-1, TIM-3 and LAG-3) and transcription factor TOX. Exhausted T cells exhibited diminished cytokine secretion (e.g. IFN-γ), reduced proliferation (e.g. Ki-67), and impaired cytotoxicity. These features closely mirror exhaustion observed in tumour-infiltrating lymphocytes and chronic infection settings. Checkpoint blockade was evaluated for functional rescue. Anti-PD-1 restored partial proliferation and modest IFN-γ production. However, neither agent fully reversed exhaustion, as other inhibitory pathways remained active. These findings align with clinical observations where monotherapy yields partial rescue. Our model thus enables quantitative assessment of exhaustion reversal and supports combinatorial checkpoint strategies. To generate sufficient antigen-specific T cells for high-throughput assays, we employed artificial antigen-presenting cells (aAPCs) derived from engineered K562 lines expressing diverse HLA alleles and co-stimulatory ligands. This platform supports expansion of rare endogenous T cells to >10⁸ cells per donor, preserving native TCR expression. Functional validation included CMV-specific and MART-1-specific T cells, which demonstrated antigen-specific cytotoxicity and cytokine responses. This scalable and physiologically relevant assay system permits precise modelling of T cell exhaustion and facilitates systematic evaluation of immunotherapeutic interventions. It serves as a reliable platform for the quantitative screening of agents that inhibit or reverse T cell exhaustion, thereby supporting the rational development of advanced immunotherapies.", "source_company": "RoukenBio", "source_org_type": "公司", "row_number": 995, "target_meta": "PD1", "MOA_meta": "抑制剂"}, {"drug_name": "novel ADC candidates", "company": "TenSixty Biosciences", "org_type": "公司", "target": "未披露", "modality": "ADC", "importance_level": "中", "total_score": 67.5, "institution_score": 65, "track_score": 90, "milestone_score": 45, "field_heat_score": 75, "bonus_score": 3, "brief_reason": "基于AI多组学发现的新型肿瘤选择性靶点（SCLC中肿瘤特异性低糖基化表位），开发新一代ADC候选物，但靶点具体名称未披露。公司为早期美国biotech，ADC赛道热度高但仍处preclinical早期阶段。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4292", "id": "ylXM_5wBX1NQZOEH-LG6", "source_drug_name": "novel ADC candidates", "title": "Leveraging AI-enhanced multi-omics discovery of novel tumor-selective targets for ADC development", "abstract_text": "TenSixty Biosciences employs an innovative AI-enhanced multi-omics discovery framework to enable the development of next-generation antibody-drug conjugates (ADCs). This integrated approach identified novel tumor-selective targets with high therapeutic potential by combining:\n1. Multi-dimensional omics analysis integrated with advanced AI analytics to uncover therapeutically relevant cancer targets\n2. Specialized proteomic profiling focused on unique post-translational modifications (PTMs) that reveal tumor-specific variants of targets, enabling enhanced tumor-selective targeting\n3. Proprietary antibody discovery and engineering generates tumor-selective antibodies directed against these variants, yielding highly potent ADC candidates\nApplied to small cell lung cancer (SCLC), this framework identified a novel therapeutic target exhibiting tumor-specific hypoglycosylation. Antibodies directed against the epitope exposed by altered glycosylation showed exceptional tumor selectivity and markedly enhanced ADC efficacy. AI-driven integration across discovery and development stages further accelerated target validation and candidate optimization.", "source_company": "TenSixty Biosciences", "source_org_type": "公司", "row_number": 17, "target_meta": "not available", "MOA_meta": "抗体偶联药物"}, {"drug_name": "NL019", "company": "Naliean Therapeutics Co. Ltd", "org_type": "公司", "target": "TROP2/NECTIN4", "modality": "ADC", "importance_level": "中", "total_score": 67.5, "institution_score": 45, "track_score": 90, "milestone_score": 65, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "NL019为基于NanoOne™平台的nanobody双靶点TROP2/NECTIN4 ADC，靶向两大热门TAA并搭载微管抑制剂，展现优异肿瘤穿透与协同抗瘤活性。机构为新兴中国biotech得45分，热门ADC+双靶点+preclinical强效数据及即将进入FIH综合打分中偏高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5349", "id": "71XM_5wBX1NQZOEH-LC5", "source_drug_name": "NL019", "title": "NL019: A next-generation TROP2/NECTIN4 dual-target nanobody-based ADC developed from the NanoOne™ Platform", "abstract_text": "Background:\nWhile antibody-drug conjugates (ADCs) have transformed oncology treatment, conventional IgG-based ADCs are constrained by suboptimal tumor penetration, heterogeneous antigen expression, and Fc receptor-mediated immune toxicity. NanoOne™, developed by Naliean Therapeutics, is an innovative nanobody-based modular ADC platform that redefines ADC engineering through molecular miniaturization, structural precision, and payload flexibility.\nMethods:\nNanoOne™ integrates multiple VHH nanobody modules (<54 kDa) to achieve deep tumor penetration and broad recognition of tumors with diverse tumor-associated antigen (TAA) profiles. Its proprietary Site-Specific Dual-Payload Conjugation enables precise stoichiometric control (1:2, 2:1, 2:2, etc.) for single or dual payloads with outstanding homogeneity. The design incorporates a highly hydrophilic and stable linker that confers excellent developability. Fc domains are removed to avoid Fc receptor-mediated toxicity to immune cells while maintaining optimal half-life and enhancing tumor microenvironment accumulation.\nResults:\nNL019, a TROP2/NECTIN4 dual-target ADC armed with a microtubule inhibitor, demonstrated potent and synergistic activity in vitro—including dual-target binding, internalization, and cytotoxicity—while minimizing on-target toxicities seen in single-target ADCs. In multiple xenograft and CDX models, NL019 achieved superior, dose-dependent antitumor efficacy versus benchmark ADCs targeting TROP2 or NECTIN4.\nConclusions:\nNL019 exemplifies the disruptive potential of NanoOne™, combining advanced molecular architecture, precision one/dual-payload conjugation, and superior tumor selectivity. Supported by strong preclinical efficacy and developability, NL019 is advancing toward first-in-human trials. Given the broad expression of TROP2 and NECTIN4 across epithelial malignancies, NL019 has the potential to establish a new generation of broad-spectrum ADC therapeutics.", "source_company": "Naliean Therapeutics Co. Ltd", "source_org_type": "公司", "row_number": 160, "target_meta": "TROP2,NECTIN4", "MOA_meta": "抗体偶联药物"}, {"drug_name": "LPD002", "company": "Lepu Biopharma Co., Ltd.", "org_type": "公司", "target": "PD-1", "modality": "fusion protein", "importance_level": "中", "total_score": 67.5, "institution_score": 65, "track_score": 85, "milestone_score": 45, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "LPD002为新型抗PD-1/IL-2融合蛋白，通过PD-1阻断结合工程化IL-2 mutein实现肿瘤浸润T细胞靶向激活，降低系统毒性。Lepu为中国专注肿瘤的上市biotech公司，赛道为热门PD-1融合细胞因子但仍处preclinical，综合潜力中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9644", "id": "_1XM_5wBX1NQZOEH-LG6", "source_drug_name": "LPD002", "title": "LPD002, a novel anti-PD-1/IL-2 fusion protein, demonstrates potent antitumor activity in preclinical studies", "abstract_text": "Background: The advancement of immunotherapy has significantly improved the survival outcomes for patients with malignant tumors. IL-2 therapy has demonstrated potential in activating tumor-infiltrating antigen-specific T cells and inducing durable anti-tumor responses. However, it often triggers severe systemic toxicities. To improve the therapeutic index, a variety of engineered IL-2 analogs have been developed.\nMethods: To overcome the challenges of PD-1 blockade and IL-2 therapies, we engineered a novel fusion protein, LPD002, which combines a humanized anti-PD-1 antibody and an engineered IL-2 mutein. The anti-PD-1 antibody portion delivers the IL-2 mutein payload to PD-1+ tumor-infiltrating T cells while blocking the immune-inhibitory signals of the PD-1 pathway. The IL-2 mutein component of LPD002 has been engineered to retain its binding activity to the IL-2 receptor alpha (IL-2Rα) subunit and attenuated afﬁnity for the IL-2 receptor beta and gamma (IL-2Rβγ) complex, which is designed to maintain peripheral tolerance and activate tumor-infiltrating T cells, thereby mitigating the systemic toxicity associated with IL-2 therapy. We systematically assessed the functional properties of LPD002 through PD-1 blockade and IL-2 signaling assays. The anti-tumor efficacy of LPD002 was investigated using PD-1 humanized mouse models. Meanwhile, we also evaluated its PK performance in cynomolgus monkeys.\nResults: In IL-2 reporter assays, LPD002 induced enhanced pSTAT5 signaling in PD-1-expressing reporter cells compared with PD-1-null cells. LPD002 also activated pSTAT5 signaling and promoted the proliferation of both activated CD4+ and CD8+ T cells in human PBMCs. Moreover, in both PD-1-sensitive and PD-1-resistant CDX models, LPD002 demonstrated superior anti-tumor efficacy and was well-tolerated. In cynomolgus monkeys, LPD002 displayed a favorable pharmacokinetic profile.\nConclusion: LPD002 represents a novel immunotherapeutic strategy that integrates PD-1 blockade with tumor-focused IL-2 activation, eliciting potent anti-tumor activity while reducing systemic toxicity. These preclinical findings demonstrate that LPD002 is a promising therapeutic candidate for solid tumors and warrants further clinical investigation.", "source_company": "Lepu Biopharma Co., Ltd.", "source_org_type": "公司", "row_number": 285, "target_meta": "PD1", "MOA_meta": "融合蛋白"}, {"drug_name": "KRASG12D/HLA-A*11-specific TAG-T cells", "company": "NDV Therapeutics Corp.", "org_type": "公司", "target": "KRASG12D/HLA-A*11", "modality": "CAR", "importance_level": "中", "total_score": 67.5, "institution_score": 45, "track_score": 90, "milestone_score": 55, "field_heat_score": 85, "bonus_score": 3, "brief_reason": "靶向KRAS G12D/HLA-A*11的TCR-mimic TAG-T细胞（基于γδT的异体细胞疗法），针对难成药KRAS突变癌；机构为小型/未知biotech公司得中等分，赛道为热门细胞治疗+neoantigen TCR-mimic靶向高热度KRAS得高分，前临床体外/体内活性+优化CSR显示较强preclinical强度但无临床里程碑。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5232", "id": "UJ7M_5wBZznHJdnt_W3O", "source_drug_name": "KRASG12D/HLA-A*11-specific TAG-T cells", "title": "Development of allogeneic TCR-mimic activating gdT (TAG-T) cells targeting KRASG12D/HLA-A*11 pMHC for undruggable KRAS-mutated cancers", "abstract_text": "The therapeutic antibodies are at the vanguard of the most promising cancer treatments. Whereas conventional therapeutic antibodies have been limited to extracellular antigens, T cell receptor mimic (TCRm) antibodies can target intracellular antigens presented by cell surface major histocompatibility complex (MHC) proteins. We successfully obtained KRASG12D/HLA-A*11-specific TCRm antibodies from a phage display using a human scFv library. The affinity and target binding specificity of TCRms was validated by SPR and flow cytometry. Then, the KRASG12D/HLA-A*11-specific TAG receptor was designed as a double-chain, TCR-based construct, with the KRASG12D/HLA-A*11-specific TCRm fused to the N-terminus of the human TCR-Cγ and TCR-Cδ chain with Furin-P2A linker sequence. In vitro and in vivo cytotoxicity assays demonstrated that the KRASG12D/HLA-A*11-specific TAG-T cells exhibited high cytotoxic activity against KRASG12D/HLA-A*11-positive cells. Furthermore, TAG-T cells engineered with a co-stimulatory domain and a chimeric switching receptor (CSR) showed the highest anticancer activity and proliferation both in vitro and in vivo. Therefore, our results demonstrate that the TCRm-based TAG-T platform targeting KRASG12D/HLA-A*11 represents a novel and promising allogeneic cell therapy strategy for patients with KRAS-G12D-positive cancers.", "source_company": "NDV Therapeutics Corp.", "source_org_type": "公司", "row_number": 1003, "target_meta": "KRAS G12D,HLA-A11", "MOA_meta": "其他"}, {"drug_name": "VBC229", "company": "VelaVigo (Hong Kong) Limited", "org_type": "公司", "target": "DLL3", "modality": "TCE", "importance_level": "中", "total_score": 67.5, "institution_score": 65, "track_score": 90, "milestone_score": 40, "field_heat_score": 75, "bonus_score": 5, "brief_reason": "VBC229为靶向DLL3的双特异性T细胞衔接器（biparatopic TCE）融合拓扑异构酶I抑制剂的新分子，针对小细胞肺癌，具有双特异性和融合载药的创新机制。VelaVigo作为国内创新型biotech机构有一定实力，但摘要禁运导致仅preclinical阶段，无明确临床里程碑，赛道热门但整体开发早期。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11549", "id": "-p7M_5wBZznHJdnt_W3O", "source_drug_name": "VBC229", "title": "VBC229: A novel DLL3-targeting biparatopic T-cell engager-topoisomerase I inhibitor fusion molecule for depth and duration of response in small-cell lung cancer", "abstract_text": "Abstract is embargoed at this time.", "source_company": "VelaVigo (Hong Kong) Limited", "source_org_type": "公司", "row_number": 1126, "target_meta": "DLL3", "MOA_meta": "其他"}, {"drug_name": "B-cell-targeted CAR-T therapy", "company": "Medicilon", "org_type": "公司", "target": "CD19", "modality": "CAR", "importance_level": "中", "total_score": 67.5, "institution_score": 65, "track_score": 90, "milestone_score": 45, "field_heat_score": 85, "bonus_score": 0, "brief_reason": "该疗法为靶向CD19的CAR-T，用于SLE的B细胞清除，属于热门细胞治疗赛道且靶点经典。Medicilon作为中国头部CRO综合实力较强但非原创新药公司，本摘要仅展示人源化模型平台和LNP递送方法的前临床评估，无明确候选药物推进里程碑。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9703", "id": "DJ7M_5wBZznHJdnt_W7O", "source_drug_name": "B-cell-targeted CAR-T therapy", "title": "Humanized SLE mouse model for evaluating B-cell CAR-T therapy efficacy and safety", "abstract_text": "Systemic lupus erythematosus (SLE) is a complex autoimmune disease marked by dysregulated B-cell activation, autoantibody production, and systemic inflammation. Therapy development is limited by species-specific immune differences, poor modeling of human pathology in conventional mice, and low clinical predictive value. Similarly, immune-related adverse events (IRAEs), such as cytokine release syndrome (CRS), remain a major challenge in cell-based cancer immunotherapies like CAR-T. To address these issues, we developed a humanized preclinical SLE mouse model that mirrors human immune responses and serves as a platform to evaluate B-cell-targeted CAR-T therapies and immune toxicity.The SLE phenotype was induced by imiquimod (IMQ), a Toll-like receptor 7 agonist that activates plasmacytoid dendritic cells and B cells. In CD34⁺ humanized mice, IMQ induced a humanized SLE-like phenotype, allowing human immune cells to respond to TLR7 stimulation and closely modeling human disease.CAR-T cells were delivered in vivo using lipid nanoparticles (LNPs) conjugated with anti-CD5 antibodies to target CD5⁺ T cells. LNP internalization delivers DNA encoding a CD19-specific CAR, and transfected T cells were characterized by flow cytometry and digital droplet PCR. LNP pharmacokinetics were analyzed via LC-MS/MS, and tissue distribution was assessed by CAR gene detection.T-cell activation and CRS were monitored via multiplex assays for cytokines (IFN-γ, TNF-α, IL-2, IL-4, IL-6, IL-10) and chemokines (MCP-1, CCL5). Anti-drug antibody responses were evaluated by anti-PEG ELISA and anti-CAR MSD assays. CAR-T efficacy was assessed using serum anti-dsDNA antibodies and urinary lipocalin-2, key biomarkers of SLE activity.In summary, this humanized SLE model with integrated analytical panels provides a physiologically relevant platform for evaluating therapeutic efficacy and immune toxicity, accelerating preclinical development of human-targeted therapies for autoimmune disease and cancer immunotherapy.", "source_company": "Medicilon", "source_org_type": "公司", "row_number": 1137, "target_meta": "CD19", "MOA_meta": "其他"}, {"drug_name": "a novel hit compound", "company": "Weill Cornell Medicine", "org_type": "大学", "target": "AR/AR-V7", "modality": "molecular glue degrader", "importance_level": "中", "total_score": 67.5, "institution_score": 35, "track_score": 95, "milestone_score": 85, "field_heat_score": 90, "bonus_score": 8, "brief_reason": "分子胶机制首次靶向AR/AR-V7的N端无序结构域，实现双重降解，克服前列腺癌耐药，具有first-in-class新机制和高潜力。大学机构背景拉低分数，但赛道热度、里程碑强度和bonus亮点使其整体重要性中等偏上。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/2047", "id": "VZ7M_5wBZznHJdnt_W7P", "source_drug_name": "a novel hit compound", "title": "First-in-class dual AR/AR-V7 molecular glue degraders targeting the undruggable N-terminal domain to overcome therapeutic resistance in prostate cancer", "abstract_text": "Metastatic castration-resistant prostate cancer (mCRPC) remains a uniformly lethal malignancy, driven by persistent dependence on the androgen receptor (AR) signaling pathway. Over 90% of prostate cancer (PC) therapies target the AR ligand-binding domain (LBD). However, the selective pressure imposed by these agents inevitably promotes therapeutic resistance and disease progression, ultimately driving mortality. Expression of AR splice variants, most notably AR-V7, that lack the LBD yet remain constitutively active, is a key mechanism of treatment resistance. Clinically, AR-V7 expression is strongly associated with resistance to all AR pathway inhibitors (ARPIs), including enzalutamide and abiraterone. Alarmingly, AR-V7 is detected in >75% of men with mCRPC, yet there are no approved inhibitors—underscoring a profound unmet clinical need. Thus, directly targeting AR-V7 represents one of the most urgent and unsolved challenges in prostate cancer drug development, with clear implications for survival and quality of life. To address this challenge, we conducted a high-throughput phenotypic screen of 170,000 small molecules and identified a novel hit compound—the first-in-class dual degrader of AR-V7 and full-length AR, defined by a previously unreported chemotype. Medicinal chemistry/SAR optimization yielded potent lead compounds (IC50 <10 nM) with improved selectivity and favorable drug-like properties. This systematic optimization effort combined iterative analog synthesis, structure-activity analysis, and physicochemical profiling to deliver nanomolar potency alongside favorable solubility and stability profiles, enabling downstream in vivo evaluation. In vivo, pharmacokinetic (PK)-optimized compounds significantly suppressed tumor growth in the enzalutamide-resistant 22Rv1 xenograft model, reversed resistance, and outperformed ARV-110, the only full-length AR-PROTAC degrader in clinical trials, by >10-fold in efficacy, with no effect on mouse body weight—establishing both robust antitumor activity and excellent tolerability. Pharmacodynamic (PD) studies revealed near-complete degradation of AR/AR-V7 proteins within 24 hours of final dose, tightly correlating with rapid tumor growth inhibition. Importantly, toxicity studies across multiple dosing regimens showed no histopathological abnormalities in major organs, further supporting the translational potential of this new therapeutic class. Mechanistic studies confirmed rapid degradation of AR-V7/AR via the ubiquitin-proteasome pathway, dependent on Cullin-RING E3 ligase activity. A CRISPR-based E3 ligase screen implicated the DDB1-RBX1-Cullin-RING complex as the mediator of degradation, consistent with a molecular glue mechanism. This represents one of the first demonstrations of a molecular glue-mediated engagement of this E3 ligase complex in prostate cancer, further underscoring the novelty of our approach. Global proteomics demonstrated deep proteome coverage of the entire proteome of ~10,000 proteins and exceptional selectivity: AR/AR-V7 ranked among the top 1% of significantly downregulated proteins, while sparing all other major human nuclear receptors, including ER, PR, and GR, and avoiding liabilities of prior PROTAC-based AR degraders—highlighting strong specificity and favorable translational potential for clinical development. Using cellular thermal shift assays, AR truncation mutants, and Cryo-EM studies, we demonstrated direct binding of our lead compounds to the intrinsically disordered N-terminal domain (NTD), shared by both AR and AR-V7. We further mapped the binding site to the TAU1/AF-1 subdomain— the first demonstration of small-molecule engagement of this notoriously “undruggable” region. This provides long-sought proof-of-concept that the unstructured AR-NTD, which has defied decades of drug targeting efforts, can indeed be targeted with small molecules. Our findings therefore expand the druggable proteome to include intrinsically disordered regions, with broad implications beyond prostate cancer. Importantly, our lead compounds were able to overcome enzalutamide resistance and inhibit all clinically validated ARPIs-resistant isoforms, including LBD-domain mutations. These results suggest that our compounds deliver not only a solution for AR-V7-mediated resistance but also a generalized “resistance-proof” strategy by simultaneously targeting multiple clinically relevant AR variants. Taken together, these data establish our lead compounds as first-in-class dual AR-V7/AR molecular glue degraders with a novel NTD-targeted mechanism and strong preclinical activity. To advance toward clinical translation, the next phase of our research will systematically define the structural basis of compound-NTD interaction, evaluate drug metabolism and safety in higher-order animal models, and explore rational combination strategies with standard-of-care agents. The objective here is to define the precise molecular mechanism of action and assess therapeutic potential in clinically relevant models. Collectively, these findings support a paradigm-shifting therapeutic strategy for targeting previously “undruggable” drivers like AR-V7. Unlike all existing AR-directed therapies that target the LBD, this approach simultaneously degrades AR and AR-V7 in a single treatment, directly addressing the central clinical challenge of therapeutic resistance. Moreover, by establishing proof-of-concept for disordered protein domain-targeted glue degraders, this work opens a broadly applicable platform to drug other transcription factors and intrinsically disordered proteins implicated across multiple cancers and diseases. By enabling dual degradation of AR (the initiating oncogenic driver in PC) and AR-V7 (the lethal, treatment-resistant variant), our drug candidate has the potential to transform the treatment landscape—benefiting patients with both hormone-sensitive and advanced castration-resistant disease, while delaying or preventing AR-V7-mediated progression. Ultimately, this work charts a new course for prostate cancer therapy by providing a first-in-class approach capable of addressing the major cause of therapeutic failure, with the potential to meaningfully extend survival and improve quality of life.", "source_company": "Weill Cornell Medicine", "source_org_type": "大学", "row_number": 1182, "target_meta": "AR-v7", "MOA_meta": "降解剂"}, {"drug_name": "ATH-002", "company": "Atheron therapeutics, Ltd.", "org_type": "公司", "target": "KAT6A", "modality": "degrader", "importance_level": "中", "total_score": 67.5, "institution_score": 45, "track_score": 85, "milestone_score": 70, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "ATH-002为口服KAT6A特异性degrader，针对KAT6A扩增肿瘤尤其是乳腺癌，机制新颖可降低双抑制剂的血液毒性。机构为小型/新兴biotech非头部，赛道为热门degrader+新兴表观靶点KAT6A，preclinical数据强劲包括体内抑瘤和安全性优势。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8695", "id": "Z1XM_5wBX1NQZOEH-LG5", "source_drug_name": "ATH-002", "title": "Discovery of a highly potent and selective KAT6A degrader ATH-002 that demonstrates robust anti-tumor activity with a low risk of hematotoxicity in preclinical studies", "abstract_text": "KAT6A, a member of the MYST family of histone acetyltransferases, regulates gene transcription by acetylating histone H3K23 and thereby participates in multiple cellular processes, such as proliferation and differentiation. Amplification or overexpression of KAT6A have been observed in various cancers, including breast cancer, where it is amplified in approximately 15% of patients, highlighting its potential as a promising target for therapy. PF-07248144, the first KAT6A/6B dual inhibitor to enter the clinic, demonstrates durable anti-tumor activity in ER+HER2− metastatic breast cancer, especially in combination with fulvestrant. However, Phase 1 data also revealed hematologic dose-limiting toxicities of neutropenia and anemia. The on-target toxicities resulting from the simultaneous inhibition of KAT6A/6B, which synergistically promote hematopoietic stem cell development. Furthermore, studies have suggested that KAT6A has non-enzymatic functions by its role in DNA damage repair via interaction with PARP and by the observation that depletion of KAT6A more efficiently suppresses the proliferation of KMT2A-rearranged AML cells than blocking its acetyltransferase activity alone. These evidences provide the rationale to develop a KAT6A-specific degrader with the potential for improved efficacy and reduced hematotoxicity. Here we report a potent and oral KAT6A degrader, ATH-002. It effectively induced KAT6A degradation with DC50 <1nM, and the degradation could be abolished when E3 was inactive, suggesting a direct mediation by the ubiquitin-proteasome system via E3-ligase binding. Global proteome analysis demonstrated an excellent selectivity against proteins, including KAT6B and other MYST family members. ATH-002 robustly inhibited proliferation in KAT6A amplified cell lines, but not in cells with low KAT6A expression, indicating the activity was driven by the specific KAT6A degradation. Mechanism studies further showed that ATH-002 dose-dependently blocked the H3K23 acetylation, down-regulated ER expression, and concurrently reduced BRPF-1 level, which might be induced by a bystander degradation effect. In contrast to KAT6A/6B inhibitors, ATH-002 significantly decreased hematotoxicity, especially in the myeloid lineage with EC50>30 μM. In a KAT6A amplified xenograft model, ATH-002 effectively inhibited tumor growth, which correlated with KAT6A degradation. Besides monotherapy, ATH-002 displayed an enhanced anti-proliferation effect in combination with SERDs or CDK4/6 inhibitors without overlapping hematotoxicity, implying a potential application of KAT6A degrader and SOC therapy. Collectively, our findings support ATH-002 as a clinical candidate for the treatment of KAT6A-amplified tumors.", "source_company": "Atheron therapeutics, Ltd.", "source_org_type": "公司", "row_number": 1263, "target_meta": "KAT6A", "MOA_meta": "降解剂"}, {"drug_name": "DNA-templated proteolysis-targeting chimera (DTAC)", "company": "Arizona State University", "org_type": "大学", "target": "Cyclin D1-CDK4/6 complex", "modality": "PROTAC", "importance_level": "中", "total_score": 67.3, "institution_score": 35, "track_score": 92, "milestone_score": 75, "field_heat_score": 85, "bonus_score": 8, "brief_reason": "DTAC通过DNA模板实现Cyclin D1-CDK4/6复合物同步降解，针对传统CDK4/6抑制剂耐药及独立功能缺陷；机构为大学得分较低，但PROTAC+多蛋白复合物降解新机制+体内异种移植瘤有效性带来较高赛道与里程碑分。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6699", "id": "jZ7M_5wBZznHJdnt_W3O", "source_drug_name": "DNA-templated proteolysis-targeting chimera (DTAC)", "title": "DNA-templated, spatially controlled proteolysis targeting chimeras enable coordinated degradation of the Cyclin D1-CDK4/6 complex", "abstract_text": "Background: Hyperactivation of the Cyclin D-CDK4/6 complex drives tumor proliferation across cancers. Although CDK4/6 inhibitors provide clinical benefit, durability is limited by resistance and by Cyclin D1’s CDK-independent oncogenic functions that are not addressed by kinase blockade. A strategy that removes the entire Cyclin D1-CDK4/6 complex could suppress both kinase-dependent and independent signaling; however, Cyclin D1 lacks a druggable active site, and prior PROTACs have degraded CDK4/6 individually rather than the intact complex. These gaps motivated the development of DNA templated degraders to program geometry and enable synchronous complex degradation.\nMethods: This study engineered DNA-templated proteolysis-targeting chimeras (DTACs) by positioning a CDK4/6 binder and an E3 ligase recruiter on complementary oligonucleotides, enabling systematic variation of intermolecular distance and orientation. A panel of DTACs was profiled for target engagement and degradation (Cyclin D1, CDK4, CDK6), cell-cycle distribution, and antiproliferative activity across cancer cell models. Lead constructs were evaluated for in vivo target degradation and antitumor activity in xenograft models.\nResults: Spatial programming dictated degrader performance: DTAC variants exhibited distance- and orientation-dependent degradation of the Cyclin D1-CDK4/6 complex. The optimized construct induced synchronous loss of Cyclin D1 together with CDK4 and CDK6, yielding pronounced G1 arrest and suppression of cellular proliferation. In a xenograft mouse model, lead product exhibited potent therapeutic efficacy by effectively degrading Cyclin D1−CDK4/6 and suppressing tumor growth.\nConclusions: DNA templating provides a modular strategy to control degrader geometry and achieve synchronized degradation of multi-protein complexes. DTACs enable coordinated Cyclin D1-CDK4/6 degradation with functional pathway blockade and antitumor activity. Overall, these findings demonstrate the feasibility of DTAC as a rapid, scalable, and modular platform for the spatial control of functional inhibitors for optimal effectiveness, making it a promising method for proximity-based therapeutics.", "source_company": "Arizona State University", "source_org_type": "大学", "row_number": 1044, "target_meta": "not available", "MOA_meta": "PROTAC"}, {"drug_name": "RPT-E-037", "company": "Remedy Plan", "org_type": "biotech company", "target": "NAMPT", "modality": "inhibitor", "importance_level": "中", "total_score": 67, "institution_score": 75, "track_score": 70, "milestone_score": 50, "field_heat_score": 65, "bonus_score": 2, "brief_reason": "RPT-E-037为新型NAMPT抑制剂，针对pNETs显示良好体外选择性和与everolimus协同作用，但仅停留在preclinical阶段。机构为研究机构而非公司主导、赛道NAMPT抑制剂有一定热度但临床开发历史受毒性限制、开发阶段较早导致综合评分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8807", "id": "TVXM_5wBX1NQZOEH-LO6", "source_drug_name": "RPT-E-037", "title": "Targeting NAMPT using Novel Inhibitor RPT-E-037 in Pancreatic Neuroendocrine Tumor", "abstract_text": "Background and Objective: Advanced pancreatic neuroendocrine tumors (pNETs) respond poorly to current FDA-approved therapies, emphasizing the urgent need to find new and effective treatment targets. Nicotinamide phosphoribosyltransferase (NAMPT), a key enzyme in the NAD biosynthesis pathway, has emerged as a crucial therapeutic target in pNETs. Despite its importance, specific inhibitors directly targeting NAMPT for pNET treatment are currently lacking. This study aimed to evaluate the efficacy of RPT-E-037, a novel NAMPT inhibitor, in preclinical models of pNETs. Methods: Growth inhibition was determined by MTT, colony formation and apoptosis assays. We also measured growth arrest using cell cycle analysis. Expression of gene or protein was determined using quantitative PCR, and western blotting techniques. The impact of NAMPT inhibitor RPT-E-037 was evaluated in pNET in vitro cultures and in in vivo. Results: RPT-E-037 demonstrated its growth inhibitory effect in BON-1 and QGP-1 pNET cell lines at pharmacologically relevant concentrations. The inhibitory concentration-50 (IC50) were determined as 0.3 and 1.2 micromolar (µM) in BON-1 and QGP-1 cells respectively. Importantly, RPT-E-037 demonstrated selectivity, showing no adverse effects on normal islet cells (ABC-TC4286, AcceGen) at concentrations effective against tumor cells (reflected by its 40-folds higher IC50). In addition, growth inhibitory effect of RPT-E-037 significantly rescued by nicotinic acid (niacin) treatment in BON-1 cells. Niacin also diminishes its colony reduction and apoptotic ability of RPT-E-037 in this cell line. The novel NAMPT inhibitor RPT-E-037 was shown to induce “DNA synthesis (S) phase” cell cycle arrest. However, niacin treatment switches “S phase” cell cycle arrest to “G0/G1 phase” cell cycle arrest. RPT-E-037 synergized with pNETs standard of care mTOR targeted agent everolimus in both BON-1 and QGP-1 cell lines leading to superior cell deaths (CI<1). The in vivo efficacy of RPT-E-037 in BON-1 and QGP-1 cell line derived xenografts (CDxs) are under way. Conclusion: For the first time, this study reveals the therapeutic potential of RPT-E-037, a new NAMPT inhibitor, for pNETs in preclinical models. RPT-E-037 shows promise as a novel NAMPT inhibitor and deserves further clinical investigation for pNETs.Generative AI was used for improving the language of the abstract.", "source_company": "Barbara Ann Karmanos Cancer Institute\nBarbara Ann Karmanos Cancer Institute, Wayne State University", "source_org_type": "研究机构\n医院", "row_number": 148, "target_meta": "NAMPT", "MOA_meta": "抑制剂"}, {"drug_name": "AIG07025", "company": "AIGEN Sciences", "org_type": "公司", "target": "USP1", "modality": "inhibitor", "importance_level": "中", "total_score": 67, "institution_score": 65, "track_score": 85, "milestone_score": 45, "field_heat_score": 75, "bonus_score": 0, "brief_reason": "AIG07025为AIGEN Sciences开发的强效选择性USP1抑制剂，靶向DNA损伤修复通路，具有与PARP抑制剂广泛联合潜力。机构为AI驱动的韩国新兴biotech，得分中等；赛道USP1抑制剂在HRD/BRCA肿瘤中热度高，但仅preclinical且摘要 embargoed，整体重要性中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11456", "id": "2FXM_5wBX1NQZOEH-LG6", "source_drug_name": "AIG07025", "title": "Discovery and preclinical characterization of AIG07025, a potent and selective USP1 inhibitor with broad combination potential", "abstract_text": "Abstract is embargoed at this time.", "source_company": "AIGEN Sciences", "source_org_type": "公司", "row_number": 200, "target_meta": "USP1", "MOA_meta": "抑制剂"}, {"drug_name": "IL10-TCE", "company": "Changping Laboratory", "org_type": "研究机构", "target": "未披露", "modality": "TCE", "importance_level": "中", "total_score": 67, "institution_score": 45, "track_score": 85, "milestone_score": 75, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "IL10-TCE为可裂解型IL-10融合TCE，通过整合IL-10克服TCE诱导的T细胞衰竭，实现实体瘤完全消退，无明显毒性。机构为国内新型研究机构非头部药企，赛道TCE+IL-10创新机制热度高，前临床多模型强效数据支持较高潜力。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9658", "id": "1VXM_5wBX1NQZOEH-LG6", "source_drug_name": "IL10-TCE", "title": "A cleavable IL10-TCE counteracts TCE-induced T cell dysfunction and eradicates solid tumors without toxicity", "abstract_text": "The clinical success of T cell engagers (TCEs) in hematologic malignancies has been difficult to replicate in solid tumors due to limited efficacy and on-target toxicities, partly driven by CD3-directed activation-induced cell death (AICD) and exhaustion of tumor-infiltrating lymphocytes (TILs). To overcome T cell dysfunction in the tumor microenvironment, we found that IL-10 receptor expression is enriched on antigen-specific T cells and that exogenous IL-10 markedly reduces T cell death while preserving overall T cell numbers. Guided by this insight, we engineered a series of IL-10-integrated TCE formats and identified an optimized design in which IL-10 is fused to the N-terminus of the anti-CD3 arm in a cleavable configuration, generating a pro-TCE (IL10-TCE) with favorable biochemical properties and potent antitumor activity without detectable toxicity. The IL10-TCE enhanced effector function and substantially expanded both total and antigen-specific T cells within tumors, resulting in complete regression of established solid tumors and metastatic lesions across multiple syngeneic and xenograft models, including colon cancer, melanoma, and pancreatic cancer. These findings establish IL-10 incorporation as a generalizable strategy to overcome TCE-induced T cell dysfunction, enabling robust tumor eradication and durable immune protection.", "source_company": "Changping Laboratory", "source_org_type": "研究机构", "row_number": 461, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "DLL3 bi-epitope compound nanobody CAR T cells", "company": "iCell Gene Therapeutics", "org_type": "公司", "target": "DLL3", "modality": "CAR", "importance_level": "中", "total_score": 67, "institution_score": 55, "track_score": 85, "milestone_score": 60, "field_heat_score": 75, "bonus_score": 3, "brief_reason": "靶点为DLL3，双表位纳米抗体复合CAR-T并搭载IL-18装甲，针对SCLC等高侵袭性神经内分泌瘤；机构为专注CAR细胞疗法的临床阶段小型biotech，非头部MNC，得分中等，赛道为热门细胞治疗+新兴固瘤靶点DLL3（伴随ADC/TCE进展），但仍处preclinical阶段，综合潜力中偏上。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9405", "id": "8FXM_5wBX1NQZOEH-LO6", "source_drug_name": "DLL3 bi-epitope compound nanobody CAR T cells", "title": "Preclinical evaluation of armored DLL3 biepitope compound nanobody CAR T cells", "abstract_text": "Introduction\nDelta-like ligand 3 (DLL3) is markedly and selectively expressed in small cell lung cancer (SCLC) and other high-grade neuroendocrine tumors with minimal expression in normal tissues, making it an attractive target for cellular immunotherapy. DLL3-directed CAR approaches in solid tumors have shown limited durability, underscoring the need for improved potency. To address these challenges, we developed DLL3 bi-epitope compound nanobody CAR T cells. We incorporate IL-18 armoring to enhance effector cell survival and function. Herein we report the feasibility of an armored DLL3 bi-epitope cCAR T construct.\nExperimental Procedures\nAlpacas were immunized with recombinant human DLL3 extracellular domain protein. Peripheral blood mononuclear cell (PBMC) mRNA was extracted and converted into a VHH (nanobody) to generate a library. The library was panned against DLL3 antigen to enrich for high-affinity binders, which were identified through ELISA screening and cellular binding analysis by flow cytometry. VHH clone sequencing were used to generate our cCAR. The DLL3 bi-epitope cCAR T is comprised of two unique and independently functioning CAR units targeting different DLL3 epitopes reducing risk of tumor evasion due to antigenic variation. A DLL3-targeting nanobody pair was used to generate DLL3 bi-epitope cCAR. Human T cells were activated and transduced to produce CAR T cells. CAR expression was assessed by flow cytometry. Cytotoxicity was evaluated using SHP-77 (endogenous DLL3⁺) and REH-DLL3xp (overexpressing DLL3) targets. NSG mice received CAR T cells to assess antitumor activity.\nResults\nThe bi-epitope DLL3 cCAR T construct demonstrates potent cytotoxicity lysing target cells in vitro and in vivo. At various effector-to-target ratios, the cCAR was observed to have strong killing activity and specificity against the primary tumor cell line and artificially DLL3-\nexpressing cell line. The cCAR also demonstrated strong potency in SHP-77 xenograft mouse models.\nConclusions\nOur bi-epitope armored DLL3 cCAR T therapy demonstrated exceptional efficacy in vitro and in vivo. These results support future investigation of our cCAR in patients with SCLC and/or DLL3 expressing neuroendocrine tumors.", "source_company": "iCell Gene Therapeutics", "source_org_type": "公司", "row_number": 821, "target_meta": "DLL3", "MOA_meta": "其他"}, {"drug_name": "designed live bacterial therapeutic", "company": "mbiomics Inc. / mbiomics GmbH", "org_type": "公司", "target": "未披露", "modality": "other", "importance_level": "中", "total_score": 67, "institution_score": 65, "track_score": 75, "milestone_score": 55, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "该药物为设计型活细菌治疗剂（live bacterial therapeutic），旨在通过重塑肠道微生物组改善ICI响应，但具体靶点/菌株未披露。mbiomics为欧洲新兴microbiome biotech（2020成立，获1300万欧元A轮），赛道为热门的microbiome-based LBP与肿瘤免疫协同，模型预测显示潜力但仍处preclinical建模阶段。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3357", "id": "_VXM_5wBX1NQZOEH-LO6", "source_drug_name": "designed live bacterial therapeutic", "title": "A designed live bacterial therapeutic restores responder-like microbiome profiles and improves immune checkpoint inhibitor (ICI) response in a predictive model", "abstract_text": "Background: The gut microbiome has been shown to predict response to ICI, but associations of individual species have not been statistically robust or reproducible. Fecal microbial transplant (FMT) has been reported to improve response probability in melanoma and kidney cancer, but drug development has focused on very simple microbial consortia.\nMethods: We sought to replicate the therapeutic benefits of FMT for improving response to ICIs in a model, and design therapeutic microbial consortia that when added to a patient’s gut microbiome could improve response rates to ICIs. We trained a machine learning model to predict response to ICI, based on gut microbiome species profiles from baseline samples in patients starting ICI therapy, and used it to evaluate candidate therapeutic consortia intended to improve response to ICI. We trained a machine learning model to predict responders (R) vs. non-responders (NR) to ICI, based on baseline gut microbiome species profiles from patients starting ICI therapy (n=418). Parameters were fixed and called NR vs. R model. We built therapeutic consortia designed around donor FMT and ICI response-related species and mechanisms. ICI patients can be NR for many reasons, so we next focused on patients where the baseline gut microbiome had good predictive value for IO response (n=257) and asked whether FMT and our therapeutic consortia would improve response probabilities.\nResults: Publicly-available data from 418 NSCLC patients was analyzed. The median age was 65 years (range 24-92), 260 men, 63% were on at least 2nd line therapy. 19.4% received antibiotics near the start of ICI, and 118 of 271 had tumors with PD-L1 <50%. Our model had mean AUC 0.62 for predicting response in hold-out test sets (patients never seen by the model), and discriminated OS curves (p<0.0001). Focusing on patients where the gut microbiome model had good predictive value (n=257), we showed that in agreement with clinical experience, healthy donor FMT improves response rates in our model when added to baseline patient microbiomes and outcomes are exposure-dependent (i.e.modeling increasing fractions of FMT species engrafting and replacing increasing fractions of patient baseline microbiomes). We showed that our candidate therapeutic consortia improve response rates when added to baseline patient microbiomes, and outcomes are again exposure-dependent. Conclusions: Our candidate therapeutic consortia have promise for improving response rates in patients on ICI therapy. We isolated bacteria to culture these consortia, which we are developing to combine with ICI.\nConclusions: Our candidate therapeutic consortia have promise for improving response rates in patients on ICI therapy. We isolated bacteria to culture these consortia, which we are developing to combine with ICI.", "source_company": "mbiomics Inc.\nmbiomics GmbH", "source_org_type": "公司", "row_number": 827, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "ACE-106", "company": "Acerand Therapeutics (Hong Kong) Limited", "org_type": "公司", "target": "PARP1", "modality": "inhibitor", "importance_level": "中", "total_score": 67, "institution_score": 65, "track_score": 75, "milestone_score": 60, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "ACE-106为高选择性PARP1抑制剂，属于新一代PARP抑制剂赛道，具有潜在best-in-class特性。机构为临床阶段中国biotech，FIC临床1/2期更新显示良好耐受性和初步疗效，赛道热度较高但非最热门靶点，综合潜力中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/12082", "id": "PZ7M_5wBZznHJdnt_W3O", "source_drug_name": "ACE-106", "title": "Updated results from a first-in-human phase 1,2 study of ACE-106, a highly selective and potentially best-in-class PARP1 inhibitor in advanced solid tumors", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Acerand Therapeutics (Hong Kong) Limited", "source_org_type": "公司", "row_number": 1232, "target_meta": "PARP1", "MOA_meta": "抑制剂"}, {"drug_name": "XYA02-8", "company": "Xyone Therapeutics Inc", "org_type": "公司", "target": "MUC1-C", "modality": "ADC", "importance_level": "中", "total_score": 66.5, "institution_score": 45, "track_score": 85, "milestone_score": 75, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "靶向MUC1-C的首创exatecan ADC，解决MUC1-N脱落导致的靶点不可靠问题，在mCRC CDX和PDX模型中显示出强效肿瘤抑制和良好安全性。机构为初创biotech，得分一般；ADC+热门肿瘤靶点+preclinical强效数据（包括肿瘤回归和高剂量安全裕度）带来较高赛道和里程碑分，总分中等偏上。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4609", "id": "_VXM_5wBX1NQZOEH-LK6", "source_drug_name": "XYA02-8", "title": "MUC1-C-directed exatecan ADC induces genotoxic stress and transcriptional suppression of UPR-inflammatory pathways in metastatic colorectal cancer", "abstract_text": "Background:Metastatic colorectal cancer (mCRC) remains a major cause of cancer mortality and MUC1 is overexpressed in most tumors. However, no approved therapies target the tumor-anchored MUC1 antigen. The MUC1 oncoprotein consists of MUC1-N and MUC1-C, which form a heteromeric complex on the cell surface. The MUC1-N is shed into circulation and is highly heterogeneous in its glycosylation patterns across tumor types, creating both an antigen sink and unpredictable epitope presentation. This glycosylation variability can sequester MUC1-N-directed antibodies and significantly reduce consistent target engagement. In contrast, the membrane-anchored MUC1-C remains structurally accessible and uniform, representing a more reliable target for ADC development and addressing a critical unmet need in mCRC therapy.\nMethods: We generated a first-in-class exatecan-based antibody-drug-conjugate (XYA02-8) recognizing the α4 helix within the extracellular domain of MUC1-C through a cleavable linker *. In vitro, cellular and patient-derived xenograft studies were perfomed to evaluate anti-tumor potency and safety of XYA02-8.\nResults: The anti-MUC1-C monoclonal antibody displayed high-affinity binding to the MUC1-C extracellular domain and robust, ligand-driven internalization across multiple mCRC cell lines. Conjugation to exatecan via a cleavable linker yielded XYA02-8, an optimized ADC with >98% monomeric purity and a DAR of 8. XYA02-8 induced potent cytotoxicity in vitro, achieving low-nanomolar IC50 values across a panel of MUC1-expressing mCRC models. In SW620 xenografts, QW dosing x 3 at 7.5 mg/kg generated pronounced tumor growth inhibition without measurable body-weight loss or overt systemic toxicity. Transcriptomic profiling revealed a dominant exatecan-associated DNA-damage and replication-stress signature, repression of UPR regulators (DDIT4, STC2), and attenuation of pro-inflammatory signaling, concordant with increased γH2AX induction and PARP cleavage. In a MUC1-positive mCRC PDX, XYA02-8 produced substantial tumor regression with minimal toxicity, and efficacy was recapitulated in NCG mice treated at 5 mg/kg QW ×3. High-dose escalation (10× therapeutic level) resulted in negligible changes in hematologic or serum chemistry parameters, supporting a strong preclinical safety margin.\nConclusion: XYA02-8, a first-in-class MUC1-C-directed exatecan ADC, demonstrates potent and selective antitumor activity driven by efficient internalization, high DAR stability, and targeted induction of DNA-damage and replication-stress programs. Its robust efficacy across CDX and PDX models, coupled with minimal systemic toxicity at supra-therapeutic doses, positions XYA02-8 as a strong candidate for clinical translation in MUC1-positive mCRC.\n* https://patents.google.com/patent/US20230265208A1/en", "source_company": "Xyone Therapeutics Inc", "source_org_type": "公司", "row_number": 172, "target_meta": "MUC1", "MOA_meta": "抗体偶联药物"}, {"drug_name": "GO-M100B", "company": "GO Therapeutics", "org_type": "公司", "target": "Tn-MUC1", "modality": "ADC", "importance_level": "中", "total_score": 66.5, "institution_score": 45, "track_score": 85, "milestone_score": 75, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "GO-M100B为靶向肿瘤特异性Tn-糖基化MUC1的首创ADC，采用“clean target”策略实现高选择性。机构为小型美国biotech（融资有限、preclinical阶段），但ADC+新型糖表位赛道热度高，体外亚纳摩尔活性+多种PDX模型显著肿瘤消退+良好毒理，支持进入IND，整体潜力中等偏上。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4288", "id": "ylXM_5wBX1NQZOEH-LK6", "source_drug_name": "GO-M100B", "title": "Targeting tumor-specific Tn-glycoforms of MUC1 and MUC4 with first-in-class antibody-drug conjugates: Preclinical efficacy and translational potential of GO-M100B and GO-M400", "abstract_text": "Aberrant O-glycosylation in epithelial cancers generates tumor-specific neoepitopes absent from normal tissues. GO Therapeutics has developed monoclonal antibodies that selectively recognize these Tn-glycoforms on mucins, including GO-M100B, targeting Tn-MUC1, and GO-M400, targeting Tn-MUC4. These antibodies bind aberrantly truncated O-glycans presented on mucin backbones with sub- to low-nanomolar affinity and exceptional site-specificity. These programs exemplify our “clean target” approach that exploits cancer-restricted glycoepitopes to enhance selectivity and therapeutic index. Structural and biochemical characterization revealed that M100B and M400 recognize proprietary glycopeptide neoepitopes unique to malignant epithelial cells, enabling precise tumor targeting. Immunohistochemistry confirmed broad reactivity across epithelial cancers. This includes breast, lung, ovarian, pancreatic, and gastrointestinal tumors. Negligible binding was seen to normal tissues. Both antibodies were engineered as site-specific antibody-drug conjugates (ADCs) using an mc-vc-PAB-MMAE linker to generate homogeneous DAR2 conjugates. These ADCs exhibited potent, selective cytotoxicity against Tn-positive cell lines, achieving sub-nanomolar IC₅₀ values, while showing no measurable activity in Tn-negative or primary normal cell models. In vivo, M100B-vedotin and M400-vedotin induced marked tumor regression in both cell-derived (CDX) and patient-derived xenograft (PDX) models, with favorable pharmacokinetics and clean toxicology profiles in cynomolgus monkeys and mice. By targeting cancer-specific glycosylation patterns on mucins, M100B and M400 expand the therapeutic frontier of “clean target” oncology. These next-generation ADCs demonstrate exceptional tumor selectivity, strong preclinical efficacy, and favorable safety, supporting advancement into IND-enabling studies and clinical development for multiple epithelial malignancies.", "source_company": "GO Therapeutics", "source_org_type": "公司", "row_number": 223, "target_meta": "Tn-Muc1", "MOA_meta": "抗体偶联药物"}, {"drug_name": "BDB025", "company": "Syntabio", "org_type": "公司", "target": "MSH2/MSH6", "modality": "other", "importance_level": "中", "total_score": 66.5, "institution_score": 40, "track_score": 85, "milestone_score": 70, "field_heat_score": 80, "bonus_score": 8, "brief_reason": "BDB025为首创双模式小分子，通过诱导MSI-H表型并表观遗传沉默MSH2/MSH6基因，将‘冷’pMMR肿瘤转化为‘热’肿瘤，克服PD-1耐药。机构为非头部biotech得40分，赛道涉及肿瘤免疫+新机制转化策略热度高得85分，前临床模型显示显著疗效及范式转变潜力得较高分，总分中位。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5672", "id": "pFXM_5wBX1NQZOEH-LO6", "source_drug_name": "BDB025", "title": "Overcoming PD-1 resistance with a first-in-class dual-mode agent that transforms ‘cold’ tumors to ‘hot’", "abstract_text": "Background: Immune checkpoint blockade fails in most colorectal cancers (CRCs) because they are immunologically ‘cold’ and mismatch repair-proficient (pMMR). This stands in stark contrast to mismatch repair-deficient (dMMR) ‘hot’ tumors, which are highly responsive; neoadjuvant anti-PD-1 achieves a 100% clinical complete response in early-stage dMMR CRC. This profound disparity underscores the urgent need for a strategy to therapeutically convert pMMR tumors into a dMMR-like state. Current approaches lack the coordinated mechanism necessary to induce and sustain this conversion at the cellular level.\nMethods: We have designed a panel of dual-mode agents to deliver two synergistic insults to individual tumor cells, directly and indirectly disrupting DNA mismatch repair (MMR) MSH2/6 genes. Using a real-time microsatellite instability (MSI) reporter screen, we identified lead compounds that mechanistically induce a high MSI (MSI-H) phenotype. The most promising candidate was subsequently evaluated in murine models of pMMR CRC resistant to PD-1 blockade.\nResults: We identified BDB025, a potent, first-in-class dual-mode agent that induces a robust MSI-H phenotype while simultaneously epigenetically silencing critical MMR genes. Crucially, this dMMR-like conversion is achieved at very low, sub-cytotoxic dosages, demonstrating a unique non-cell-death-mediated mechanism of action. This coordinated, two-pronged attack within the same cell overwhelms the DNA mismatch repair machinery, specifically MSH2/MSH6, increases tumor mutational burden and T cell influx. Consequently, BDB025 converts ‘cold’ pMMR tumors to ‘hot’, ablates established tumors, and overcomes resistance to anti-PD-1 therapy, significantly outperforming standard agents.\nConclusion: We demonstrate a paradigm-shifting therapeutic strategy: a single molecule that pharmacologically induces a synthetic dMMR state by co-opting two synergistic mechanisms of action. Our lead candidate, BDB025, effectively breaks PD-1 resistance, paving the way to extend the curative potential of immunotherapy to the vast population of patients with pMMR cancers.\nKeywords: PD-1 resistance, colorectal cancer, MSI-H, DNA mismatch repair, MSH2, MSH6", "source_company": "Syntabio", "source_org_type": "公司", "row_number": 244, "target_meta": "MSH6,MSH2", "MOA_meta": "其他"}, {"drug_name": "NECTIN4×PD-L1 bispecific ADC", "company": "AbTis Co., Ltd", "org_type": "公司", "target": "NECTIN4 & PD-L1", "modality": "bispecific ADC", "importance_level": "中", "total_score": 66.5, "institution_score": 65, "track_score": 90, "milestone_score": 45, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "该双特异性ADC同时靶向NECTIN4（ADC热门靶点）和PD-L1（免疫检查点），整合细胞毒性和检查点阻断机制，解决异质性问题。机构为韩国中小型biotech（2023年被Dong-A ST收购），赛道极热但仍处preclinical早期阶段，综合潜力中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5752", "id": "AFXM_5wBX1NQZOEH-LG5", "source_drug_name": "NECTIN4×PD-L1 bispecific ADC", "title": "NECTIN4×PD-L1 bispecific antibody-drug conjugate integrating checkpoint blockade and targeted cytotoxicity for urothelial carcinoma and lung squamous cell carcinoma", "abstract_text": "Background: The first-line approval of enfortumab vedotin plus pembrolizumab validates the clinical rationale for combining ADCs with ICIs. However, administering two separate agents poses challenges in cost, compliance, toxicity management, and in achieving comprehensive coverage of target and immune heterogeneity. To address these limitations, we engineered a NECTIN4×PD-L1 bispecific ADC using Dong-A ST BsAb platform with an enhanced knob-into-hole (eKiH) interface that integrates NECTIN4-directed cytotoxic delivery with PD-L1 axis blockade in a single molecule. The molecule was designed to overcome resistance and spatial heterogeneity in locally advanced/metastatic urothelial carcinoma (la/mUC) and LUSC.\nMethods: High-affinity NECTIN4 and PD-L1 antibody leads were identified and assembled into Dong-A ST BsAb platform. Site-selective conjugation was applied to generate ADCs bearing MMAE, exatecan, or dual-payload configurations. Functional characterization included: (i) binding affinity and competition to both targets, (ii) internalization and payload release in NECTIN4-positive cells, and (iii) PD-1/PD-L1 reporter assays and T-cell co-culture cytotoxicity. To support clinical translation, scRNA-seq and tissue microarray-based mIHC were performed on bladder cancer and LUSC cohorts to evaluate NECTIN4/PD-L1 co-expression, spatial heterogeneity, and correlations with immune infiltration and checkpoint pathways.\nResults: scRNA-seq revealed intra-patient coexistence of NECTIN4-only, PD-L1-only, and co-expressing tumor subpopulations, with notable inter-patient variability. Multiplex IHC confirmed mosaic and cluster-type spatial heterogeneity. The bispecific ADC maintained high-affinity binding to both targets, exhibited efficient internalization and payload release in NECTIN4-positive cells, and preserved potent PD-1/PD-L1 blockade activity in reporter assays. ADCs carrying MMAE, exatecan, or dual payloads demonstrated consistent in vitro cytotoxicity across NECTIN4-high, PD-L1-high, and co-expressing tumor models, along with enhanced T cell-mediated tumor killing in co-culture. Preliminary in vivo studies showed dose-dependent tumor growth inhibition in bladder cancer and LUSC xenograft models with acceptable tolerability (detailed results pending final analysis).\nConclusions: This NECTIN4×PD-L1 bispecific ADC integrates targeted cytotoxicity (NECTIN4) and checkpoint blockade (PD-L1) into a single therapeutic agent, rationally designed to provide catch-all activity against target and immune microenvironment heterogeneity in la/mUC and LUSC. The preclinical data support evaluation as an early-line therapeutic strategy that could complement or substitute separate ADC+ICI combinations.", "source_company": "AbTis Co., Ltd", "source_org_type": "公司", "row_number": 309, "target_meta": "NECTIN4,PDL1", "MOA_meta": "抗体偶联药物"}, {"drug_name": "zCART", "company": "AbClon, Inc.", "org_type": "公司", "target": "未披露", "modality": "CAR", "importance_level": "中", "total_score": 66.5, "institution_score": 65, "track_score": 85, "milestone_score": 45, "field_heat_score": 80, "bonus_score": 4, "brief_reason": "zCART为基于cotinine开关的可切换通用CAR-T平台，靶向肿瘤抗原及免疫抑制微环境，实现多靶点灵活控制以克服实体瘤异质性，但靶点未明确披露。AbClon作为韩国上市生物技术公司有CAR-T管线进展，赛道为热门开关型CAR-T但仍处体外preclinical阶段，综合潜力中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5186", "id": "0VXM_5wBX1NQZOEH-LO6", "source_drug_name": "zCART", "title": "A universal and switchable CAR T cell therapy platform (zCART) targeting tumor antigens and the immunosuppressive microenvironment", "abstract_text": "The major hurdles in the treatment of solid tumors with chimeric antigen receptor (CAR) T cell therapies are antigen heterogeneity and the immunosuppressive tumor microenvironment. To address these challenges, we developed a universal and switchable CAR T cell therapy platform (zCART) that utilizes cotinine, a pharmacologically inert hapten, as a molecular bridge between anti-cotinine CAR T cells and tumor cells via cotinine-conjugated affibodies. First, we generated two affibody switches targeting distinct tumor-associated antigens and one affibody switch targeting an immune-oncology molecule. In vitro studies demonstrated that all three cotinine-conjugated affibodies, when combined with anti-cotinine CAR T cells, induced potent, dose-dependent cytotoxicity against target-expressing tumor cells. The combination of distinct affibody switches resulted in enhanced anti-tumor activity. These results highlight that the cotinine-based, switchable CAR T cell therapy platform enables flexible, multi-target control of CAR T cell activity and effective elimination of heterogeneous solid tumors. By decoupling antigen recognition from CAR T cell activation, the zCART platform offers a safe, versatile, and next-generation approach to overcoming tumor antigen variability and the immunosuppressive microenvironment, positioning it as a promising strategy for solid-tumor immunotherapy.", "source_company": "AbClon, Inc.", "source_org_type": "公司", "row_number": 798, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "TCIP3", "company": "Stanford University", "org_type": "大学", "target": "BCL6 (recruit p300/CBP to BCL6)", "modality": "molecular glue", "importance_level": "中", "total_score": 66.5, "institution_score": 45, "track_score": 85, "milestone_score": 75, "field_heat_score": 80, "bonus_score": 8, "brief_reason": "TCIP3为新型bivalent molecular glue，通过诱导p300/CBP接近BCL6重编程表观遗传激活细胞死亡基因，在DLBCL模型中展现亚纳摩尔级体外/体内疗效并选择性杀伤肿瘤细胞。机构为大学导致institution_score较低，但分子胶+表观遗传重编程+新机制+强劲preclinical数据（包括晶体结构、体内肿瘤消除）使赛道和里程碑热度高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10467", "id": "D1XM_5wBX1NQZOEH-LS6", "source_drug_name": "TCIP3", "title": "A bivalent molecular glue linking lysine acetyltransferases to oncogene-induced cell death", "abstract_text": "Cancer therapies that activate cell death are critical to avoid relapse. Approximately 30% of diffuse large B cell lymphoma (DLBCL) cases, the most common non-Hodgkin lymphoma, fail standard-of-care treatment regimens, highlighting the need for new death-promoting targeted therapies. Here, we introduce a gain-of-function small molecule modality that kills DLBCL cells at sub-nanomolar potency (IC50 = 0.8 nM) through induced proximity. These bivalent compounds, Lysine Acetyltransferase Transcriptional/Epigenetic Chemical Inducers of Proximity (KAT-TCIPs), leverage the endogenous activity of the co-activating KATs E1A Binding Protein p300 (p300) and CREB-Binding Protein (CBP) to drive the transcription of death-promoting genes normally repressed by oncogenes. Specifically, KAT-TCIPs recruit p300/CBP to genomic loci controlled by the master transcriptional repressor BCL6, dysregulated in ~40% of DLBCL cases, and rapidly reprogram the epigenome to promote BCL6-dependent cell cycle arrest and apoptosis. We report the first X-ray co-crystal structure of a TCIP molecule bound to p300 and BCL6, which guided the optimization of our lead KAT-TCIP, TCIP3. Additional biophysical characterization of TCIP3 revealed its function as a molecular glue that cooperatively seeds ternary complexes on chromatin. This compound exhibits robust preclinical efficacy in vivo. It ablates germinal center B cells, which are naturally enriched for BCL6 expression, in immunized mice (5 mpk bid dosed intraperitoneally) relative to vehicle controls. Additionally, TCIP3 eliminates tumors in DLBCL cell line-derived xenograft models within 11 days at the same dose. Notably, this molecule spares healthy lymphocytes and fibroblasts in cytotoxicity analyses. Collectively, our findings establish KAT-TCIPs as powerful tools for co-opting the malignant function of oncogenic drivers to activate robust cell death, with implications for precision epigenetic therapies.", "source_company": "Stanford University", "source_org_type": "大学", "row_number": 842, "target_meta": "CBP/EP300,BCL6", "MOA_meta": "分子胶"}, {"drug_name": "personalized cancer vaccine (PCV)", "company": "Xinyi Pharma (Hangzhou) Co., Ltd.", "org_type": "公司", "target": "neoantigen", "modality": "mRNA", "importance_level": "中", "total_score": 66.5, "institution_score": 45, "track_score": 90, "milestone_score": 65, "field_heat_score": 85, "bonus_score": 3, "brief_reason": "该药为基于neoantigen的mRNA个性化癌症疫苗，采用AI优化neoantigen预测和mRNA设计，靶向neoantigen具有高免疫原性潜力；机构为国内非头部公司但属企业类型，在热门mRNA+个性化疫苗赛道有preclinical小鼠模型有效性和安全性数据，综合潜力中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3651", "id": "d57ECZ0BZznHJdntvNYd", "source_drug_name": "personalized cancer vaccine (PCV)", "title": "Harnessing artificial intelligence to optimize neoantigen prediction and mRNA design for personalized cancer vaccine", "abstract_text": "Background:Neoantigen-based mRNA personalized cancer vaccines (PCV) represent a promising frontier in cancer immunotherapy. However, current neoantigen prediction strategies primarily rely on MHC binding affinity, which leads to limited accuracy in immunogenicity and results in a high false-positive rate. The precise identification of neoantigen epitopes that are efficiently presented by MHC and elicit robust immunogenicity remains a central challenge hindering the clinical application of PCV. Here, we developed EchoNeo 1.0, a multimodal deep learning-driven pipeline that innovatively integrates immunogenicity prediction with mRNA sequence design to accelerate the of application of PCV.\nMethodsThe core of pipeline is a multimodal deep learning model for immunogenicity prediction. Trained on publicly available databases (IEDB, TSNAdb v2.0, TESLA) and published immunogenicity data, the model integrates peptide/HLA pseudosequence features with multidimensional biological metrics to achieve accurate immunogenicity scoring. Neoantigen mRNA vaccines were synthesized and formulated with lipid nanoparticles (LNP), and evaluated in mouse models for safety (including toxicology and in vivo biodistribution) and therapeutic efficacy.\nResults:Approximately 3,700 peptides (8-11 amino acids) with confirmed experimental immunogenicity data were used to train and validate EchoNeo, which demonstrated superior performance in benchmark tasks against established prediction tools (e.g., DeepImmuno, IEDB Class I Immunogenicity tool) and showed excellent immunogenicity prediction accuracy on independent, clinically validated neoantigen datasets. In C57BL/6 mice intramuscularly administered with vaccine (at a maximum dose of 54 μg, approximately 2.7 mg/kg), no significant adverse changes were observed in body weight, body temperature, blood biochemistry (ALT, AST, DBIL, CREA, UREA, TG, TC, LDL, HDL, LDH, CK), or complete blood count (CBC, DIFF, and RET). In a melanoma model, the vaccine significantly inhibited tumor growth, and enhanced therapeutic effect was achieved when combined with anti-PD-1 antibody.\nConclusion:Superior immunogenicity prediction accuracy was confirmed, as well as the favorable safety and potent antitumor efficacy in mouse models. This work represents a paradigm shift from conventional affinity-based prediction to an end-to-end framework that directly assesses the immunogenicity of neoantigen peptides, holding significant promise for accelerating the development of PCV.", "source_company": "Xinyi Pharma (Hangzhou) Co., Ltd.", "source_org_type": "公司", "row_number": 948, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "DLL3-targeted CAR-T cell therapy constructed by circular RNA and antibody-conjugated lipid nanoparticles", "company": "Chinese Academy of Sciences", "org_type": "研究机构", "target": "DLL3", "modality": "CAR", "importance_level": "中", "total_score": 66.5, "institution_score": 45, "track_score": 85, "milestone_score": 75, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "靶向DLL3的体内circRNA-LNP递送CAR-T疗法，针对SCLC这一高未满足需求肿瘤。研究机构背景导致institution_score偏低，但in vivo CAR-T+circRNA+靶向LNP组合在热门赛道中具创新性，动物模型显示显著疗效和良好安全性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9375", "id": "TJ7M_5wBZznHJdnt_W3O", "source_drug_name": "DLL3-targeted CAR-T cell therapy constructed by circular RNA and antibody-conjugated lipid nanoparticles", "title": "DLL3-targeted in vivo CAR-T therapy of small cell lung cancer with lipid nanoparticles and circular RNA", "abstract_text": "Background: The survival of small cell lung cancer (SCLC) is discouraging, necessitating the development of novel targets and effective therapeutic approaches. Delta-Like Ligand 3 (DLL3) represents a promising target for the treatment of SCLC, with ongoing vigorous therapeutic strategies, including DLL3-targeted chimeric antigen receptor-T (CAR-T) cell therapy. Here, we report DLL3-targeted in vivo CAR-T therapy constructed by circular RNA (circRNA) and antibody-conjugated lipid nanoparticles (LNP), yielding promising therapeutic potential for treating SCLC.\nMethods: Circular RNAs (circRNAs) are covalently closed single-stranded RNAs that are resistant to exonuclease-mediated degradation. Compared with linear mRNA, circular RNA is more stable and efficient as translate templates, thus circRNA has been considered as “the next generation” of mRNA. RNA-LNPs were prepared via microfluidic mixing an aqueous solution of the circRNA and an ethanolic solution of the lipid components at a ratio of 3:1. LNPs were conjugated with purified rat anti-mouse CD5 (CD5-LNP) or IgG (IgG-LNP) via SATA-maleimide chemistry reaction to obtain antibody conjugated LNP-circRNA.\nResults: We have previously reported a highly efficient TREM1/DAP12-based novel multiple-chain CAR structure. In current study, we successfully synthesized and validated the feasibility of circRNA encoding DLL3-targeted CAR. To quantify the percentage of CAR-T cell in vivo, LNPs were intravenously injected into 8-week-old mice. CAR T cells in the immune organ and peripheral blood were characterised via flow cytometry 24h post injection. CD5-conjugated LNP showed a significant higher CAR-T percentage in peripheral blood (~15%) and immune organs (~12% in lymph node, ~16% in spleen, and 22% in thymus) compared to non-targeted LNP (unconjugated LNP and IgG-conjugated LNP). We further analysed the CAR-T cell duration in vivo. CD5-targeted LNP were intravenously injected into 8-week-old mice at dose of 30 ug RNA per mice. Immune organ and peripheral blood were isolated and characterised via flow cytometry at each time point. We observed that the CAR expressing T cells reached peak at 24h, then completely diminished after 5days. Lastly, using mice subcutaneous and orthotopic models, we demonstrated the efficacy of circRNA-based CAR-T therapy in SCLC tumor eradication, significantly extending survival. By Day 28 post-injection, 3/4 mice in the experimental group remained alive, whereas all in the control group had perished by Day 21. No significant increase of liver toxicity (indicated by AST and ALT) among the indicated groups, suggested favorable safety profile.\nConclusion: Leveraging antibody-conjugated LNP and circRNA, we have effectively engineered DLL3-targeted CAR-T cells in vivo, which shows effective cytotoxicity against SCLC. This research offers a promising avenue for advancing SCLC and in vivo CAR-T therapeutics.", "source_company": "Chinese Academy of Sciences", "source_org_type": "研究机构", "row_number": 1001, "target_meta": "DLL3", "MOA_meta": "其他"}, {"drug_name": "ALK208", "company": "Allink Biotherapeutics", "org_type": "公司", "target": "PD-L1/B7-H3/VEGF", "modality": "ADC", "importance_level": "中", "total_score": 66.5, "institution_score": 65, "track_score": 90, "milestone_score": 40, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "ALK208为首创PD-L1/B7-H3/VEGF三特异性ADC，整合直接杀伤、免疫检查点阻断和抗血管生成机制，靶点和modality均属热门赛道。公司为2023年成立的中国新兴biotech，虽融资活跃且快速推进其他ADC至临床I期，但机构整体仍属新兴非头部，项目处于preclinical阶段。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4476", "id": "g1XM_5wBX1NQZOEH-LG5", "source_drug_name": "ALK208", "title": "A first-in-class PD-L1/B7-H3/VEGF tri-specific ADC achieves enhanced preclinical antitumor efficacy through direct cytotoxicity, immune checkpoint blockade and VEGF inhibition", "abstract_text": "PD-L1 is an established immunotherapy target highly expressed in various solid tumors, while B7-H3 is another extensively investigated target overexpressed on a wide range of tumor cells. ADCs targeting PD-L1 or B7-H3 have entered clinical development and shown promising efficacy. PD-L1-directed ADCs may combine direct cytotoxicity and immunotherapy, demonstrating antitumor activity even in PD-L1-negative patients. However, ADC-related toxicity may limit their clinical dosing and thus restrict the full immune-mediated effects. Meanwhile, VEGF/PD-(L)1 bispecific antibodies are emerging as next-generation immunotherapies, with multiple trials exploring their combination with ADCs. Here, we developed ALK208, a trispecific ADC targeting PD-L1, B7-H3, and VEGF, conjugated to a topoisomerase I inhibitor payload. It is designed to integrate direct tumor cell killing, immune checkpoint blockade, and anti-angiogenic activity for maximal antitumor efficacy. Through optimized linker-payload design and DAR, ALK208 exhibited an improved safety profile, enabling higher dose levels to support robust PD-L1 blockade and VEGF neutralization. In preclinical studies, ALK208 simultaneously bound B7-H3, PD-L1, and VEGF with affinity comparable to monospecific antibodies. It effectively blocked VEGF/VEGFR and PD-1/PD-L1 interactions in reporter assays. Concurrent binding of B7-H3 and PD-L1 enhanced cellular binding and internalization in B7-H3/PD-L1 double-positive tumor cells, leading to more potent cytotoxicity than monospecific ADCs. VEGF-mediated crosslinking further strengthened binding, internalization, and cell-killing activity compared to a PD-L1/B7-H3 bispecific ADC. In the presence of VEGF homodimer, ALK208 also showed enhanced PD-L1 blockade in functional assays. Importantly, it did not kill activated T cells or APCs in vitro, suggesting a favorable immune safety profile. In xenograft models, ALK208 outperformed clinical-stage PD-L1 and PD-L1/B7-H3 ADCs. In summary, ALK208 is a first-in-class PD-L1/B7-H3/VEGF trispecific ADC that integrates multiple complementary mechanisms to maximize antitumor efficacy while maintaining a promising safety profile.", "source_company": "Allink Biotherapeutics", "source_org_type": "公司", "row_number": 1246, "target_meta": "PDL1,CD276", "MOA_meta": "抗体偶联药物"}, {"drug_name": "ATH-007", "company": "Atheron Therapeutics, Ltd.", "org_type": "公司", "target": "CCNE1", "modality": "molecular glue", "importance_level": "中", "total_score": 66.5, "institution_score": 45, "track_score": 90, "milestone_score": 70, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "ATH-007是一种新型高选择性CCNE1分子胶降解剂，直接靶向CCNE1扩增肿瘤，优于CDK2抑制剂的选择性和安全性。机构为小型/新兴公司得分一般，但分子胶+热门靶点CCNE1赛道热度高，前临床数据显示强降解和抗瘤活性，整体潜力中等偏上。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8733", "id": "wlXM_5wBX1NQZOEH-LS6", "source_drug_name": "ATH-007", "title": "Discovery of ATH-007, a novel, potent and highly selective CCNE1 molecule glue shows robust anti-tumor activities and better safety profile", "abstract_text": "Cyclin E1 (CCNE1) is a key cell cycle regulatory protein and binds to cyclin-dependent kinase 2 (CDK2), forming a CCNE1-CDK2 complex, which is essential for driving the cell cycle progression to S-phase for subsequent DNA replication. Amplification of the CCNE1 locus on chromosome 19q12 is prevalent in multiple tumor types, particularly in breast cancer, high-grade serous ovarian cancer, uterine tumors, and gastro-esophageal cancers. In breast cancer, amplification of CCNE1 is a potential cause of resistance to CDK4/6 inhibitor. CCNE1 amplification may also confer resistance to chemotherapy and is associated with poor overall survival. Therefore, there is a significant unmet medical need for tumors with CCNE1 amplification. Compared with CDK2 inhibitors, CCNE1 molecular glues exhibit better selectivity, thereby reducing the adverse effects caused by CDK2 inhibitors in clinical trials. Here, we report that ATH-007 is a highly selective CCNE1 degrader that demonstrates superior degradation selectivity and anti-tumor activity against CCNE1-amplified cells. ATH-007 strongly degrades CCNE1 with DC50 of <10 nM and achieves complete protein degradation (Dmax of >95%) and also shows 1000-fold degradation selectivity over other CRBN substrates, including GSPT1, CK1α, and IKZF1, etc. ATH-007 can effectively inhibit the proliferation of MKN1 cells with CCNE1 amplification, however, after the deletion of RB1 (a downstream substrate of CCNE1), the inhibitory effect of ATH-007 on MKN1-RB1-KO cells is abrogated. Across a panel of CCNE1-amplified tumor cell lines, ATH-007 potently inhibits proliferation with GI50 values ranging from 1 to 100 nM, similar to the potency of CDK2 inhibitors. In CCNE1-non-amplified cells, ATH-007 exhibits significantly superior selectivity compared to CDK2 inhibitors, rendering it the greater therapeutic window. In terms of in vitro hematotoxicity assay, ATH-007 shows no inhibitory effect on the differentiation of all lineages, while CDK2 inhibitors exhibits a strong inhibitory effect. Compared with existing CCNE1 molecular glues, ATH-007 exhibits weaker inhibition of hERG, indicating that it has potentially better safety. ATH-007 exhibits favorable PK properties, which enable us to advance this molecule to in vivo experiments. In tumor model with CCNE1 amplification, ATH-007 shows tumor suppression activity even at low doses and inhibit tumor growth in a dose-dependent manner. Furthermore, the inhibitory activity against tumors is correlated with the degradation of CCNE1.", "source_company": "Atheron Therapeutics, Ltd.", "source_org_type": "公司", "row_number": 1272, "target_meta": "CCNE1", "MOA_meta": "分子胶"}, {"drug_name": "ARTS-051", "company": "Allorion Therapeutics", "org_type": "公司", "target": "Werner helicase", "modality": "inhibitor", "importance_level": "中", "total_score": 66, "institution_score": 70, "track_score": 85, "milestone_score": 40, "field_heat_score": 80, "bonus_score": 0, "brief_reason": "ARTS-051为Allorion Therapeutics开发的Werner helicase (WRN)抑制剂，针对MSI-H结直肠癌模型显示广谱有效，靶向MSI-H肿瘤合成致死机制具有较高赛道热度。机构为国内临床前biotech公司，摘要禁运导致仅preclinical表征，无明确临床里程碑，综合潜力中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11481", "id": "XZ7M_5wBZznHJdnt_W7P", "source_drug_name": "ARTS-051", "title": "Characterization of ARTS-051, a potent and selective Werner helicase inhibitor effective against a broad range of MSI-H colorectal cancer models", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Allorion Therapeutics", "source_org_type": "公司", "row_number": 162, "target_meta": "WRN", "MOA_meta": "抑制剂"}, {"drug_name": "anti-PD-L1", "company": "Novocure Ltd", "org_type": "公司", "target": "未披露", "modality": "other", "importance_level": "中", "total_score": 65.8, "institution_score": 75, "track_score": 65, "milestone_score": 50, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "该项研究中anti-PD-L1为已知免疫检查点抑制剂，用于联合TTFields增强SCLC免疫化疗效果，但药物本身靶点未新披露。Novocure作为专注TTFields的国外中型biotech公司（市值约13-14亿美元，已有FDA批准产品），preclinical数据展示协同潜力但无新机制突破，故综合评分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5621", "id": "VVXM_5wBX1NQZOEH-LO6", "source_drug_name": "anti-PD-L1", "title": "Efficacy of Tumor Treating Fields (TTFields) together with standard chemotherapy and PD-L1 blockage in preclinical models of small cell lung carcinoma", "abstract_text": "Introduction: SCLC is a highly aggressive cancer treated with platinum-etoposide chemotherapy, immunotherapy, and radiotherapy. Tumor Treating Fields (TTFields), an FDA-approved therapy for several solid tumors, has been shown to enhance chemotherapy and immunotherapy treatment efficacy. Here, we assessed the potential of TTFields to augment the effects of chemotherapy and PD-1 inhibition in preclinical SCLC models.\nMethods: Human SCLC cell lines (H196, DMS-53) were exposed to 150 kHz TTFields (1.62 V/cm RMS, 120 h; 1 V/cm RMS, 72 h), alone or with the chemotherapy combination cisplatin and etoposide (0.15 µM and 0.3 µM; 0.25 µM and 0.5 µM). Treatment efficacy was assessed by cell count and colony formation, combined to determine overall response. Protein expression in the Fanconi anemia-BRCA DNA repair pathway was analyzed by western blot, and DNA damage was quantified via γH2AX fluorescence microscopy. Immunogenic cell death (ICD) was evaluated by flow cytometry for ATP depletion (quinacrine staining) and surface calreticulin, and by Homogeneous Time Resolved Fluorescence (HTRF) assay for HMGB1 release. In vivo, mice orthotopically implanted with murine KP3 SCLC cells received TTFields (150 kHz) or sham-heat for 10 days starting seven days post-implantation, with or without cisplatin (2 mg/kg), etoposide (8 mg/kg), and anti-PD-L1 (10 mg/kg) administered intraperitoneally. Tumor burden was monitored by MRI at treatment initiation and completion, and tumor weight measured at endpoint. DNA damage was examined by γH2AX immunohistochemistry and by flow cytometry of tumor single-cell suspensions.\nResults: TTFields and the chemotherapy combination each reduced cell counts and increased overall treatment efficacy compared with control, with greater effects observed when applied simultaneously. While TTFields or chemotherapy alone induced minimal DNA damage and ICD, concurrent application markedly enhanced both endpoints relative to control and single treatments. TTFields exposure suppressed expression of Fanconi anemia-BRCA pathway proteins essential for homologous recombination repair. In mice, TTFields reduced tumor growth, with further suppression observed when delivered together with cisplatin, etoposide, and anti-PD-1 therapy. Enhanced DNA damage was likewise detected under concurrent TTFields and immunochemotherapy exposure.\nConclusions: In preclinical SCLC models, TTFields showed antitumor activity and augmented the effects of standard chemoimmunotherapy. By interfering with DNA repair, TTFields intensify the cytotoxic impact of DNA-damaging chemotherapeutics, while their ability to trigger immunogenic cell death may potentiate immune checkpoint blockade. These complementary mechanisms highlight TTFields as a promising modality to reinforce the efficacy of existing therapeutic approaches in SCLC.", "source_company": "Novocure Ltd", "source_org_type": "公司", "row_number": 53, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "a potential first-in-class CDH17/CEACAM5 targeted bispecific antibody drug conjugate", "company": "Haisco Pharmaceutical Group Co., Ltd.", "org_type": "公司", "target": "CDH17/CEACAM5", "modality": "ADC", "importance_level": "中", "total_score": 65.8, "institution_score": 65, "track_score": 85, "milestone_score": 40, "field_heat_score": 75, "bonus_score": 3, "brief_reason": "该双特异性ADC靶向CDH17和CEACAM5，主要针对胃肠道肿瘤如结直肠癌，属于热门ADC+双靶点赛道，但摘要仍处于embargoed的preclinical早期阶段。机构为国内有一定实力的上市药企但非头部TOP，preclinical无具体数据披露导致里程碑分较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11406", "id": "zFXM_5wBX1NQZOEH-LK6", "source_drug_name": "a potential first-in-class CDH17/CEACAM5 targeted bispecific antibody drug conjugate", "title": "Preclinical development of a potential first-in-class CDH17/CEACAM5 targeted bispecific antibody drug conjugate (ADC)", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Haisco Pharmaceutical Group Co., Ltd.", "source_org_type": "公司", "row_number": 618, "target_meta": "CDH17,CEACAM5", "MOA_meta": "抗体偶联药物"}, {"drug_name": "CQ-0736", "company": "Santolecan Pharmaceuticals LLC", "org_type": "公司", "target": "pan-KRAS", "modality": "other", "importance_level": "中", "total_score": 65.5, "institution_score": 45, "track_score": 85, "milestone_score": 70, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "CQ-0736为多糖基双药偶联物，利用macropinocytosis选择性递送DTX和GLA靶向pan-KRAS肿瘤，非直接靶向KRAS蛋白但针对RAS驱动肿瘤。机构为美国初创公司得分中等，赛道结合热门KRAS+创新递送机制热度高，preclinical数据强劲优于RMC-6236和Krazati获较高里程碑分，总分中等偏上。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6695", "id": "fZ7M_5wBZznHJdnt_W3O", "source_drug_name": "CQ-0736", "title": "CQ-0736, a new polysaccharide-based therapeutic modality, targets pan-KRAS tumors with robust antitumor activity via macropinocytosis", "abstract_text": "Oncogenic RAS mutations are among the most prevalent and intractable drivers of human cancer, present in nearly 20% of cases. These mutations not only fuel uncontrolled tumor growth but also reprogram cellular metabolism by dramatically increasing macropinocytosis. This unique “nutrient scavenging” pathway is critical for RAS-driven cancer cells yet largely dispensable in normal tissues and presents a powerful and underexploited therapeutic opportunity.\nTo address this unmet need, we developed CQ-0736, a first-in-class “Trojan horse” therapeutic that exploits macropinocytosis to selectively co-deliver two synergistic drugs into the pan-KRAS tumors. CQ-0736 is a polysaccharide-based dual-drug conjugate consisting of a 100 kDa dextran backbone covalently grafted with docetaxel (DTX) and gamma-linolenic acid (GLA). This drug construct converts the RAS-driven tumor cell membrane from a “natural barrier” into an “active transport interface”, enabling unprecedented levels of intracellular drug accumulation specifically at tumor sites.Preclinical studies demonstrate the highly transformative potential of CQ-0736. In vitro, it exhibited markedly greater cytotoxicity than parent DTX across multiple pan-KRAS cancer cell lines harboring KRASG12D, KRASG12C, and KRASWT mutations. Several in vivo xenograft models showed that CQ-0736 achieved more than 95% tumor growth inhibition without weight loss or observed toxicity, regardless of KRAS mutation status. Remarkably, the direct head to head in vivo comparisons revealed that CQ-0736 significantly outperformed the word class pan-RAS inhibitor RMC-6236 and the marketed KRAS targeted drug Krazati, displaying superior efficacy, longer durability, and much less drug resistance.Mechanistic analyses confirmed that CQ-0736 robustly suppresses proliferation (decreasing PCNA and Ki-67) while driving apoptosis (elevating cleaved PARP), producing superior effects to parent DTX. These findings underscore the conjugate’s dual impact on tumor biology and highlight its potential to overcome key limitations of both conventional chemotherapy and next-generation targeted RAS inhibitors, including systemic toxicity and acquired resistance.\nConclusion: CQ-0736 represents a highly innovative and clinically promising therapeutic strategy for RAS-driven cancers, a disease with devastating prognosis and few effective options. By turning a fundamental vulnerability of RAS-driven tumors into a drug delivery advantage, CQ-0736 opens a new therapeutic paradigm with the potential to significantly improve outcomes for patients with some of the most aggressive and treatment-resistant malignancies.", "source_company": "Santolecan Pharmaceuticals LLC", "source_org_type": "公司", "row_number": 267, "target_meta": "KRAS", "MOA_meta": "其他"}, {"drug_name": "HER2xAXL BsAb", "company": "AbTis Co., Ltd", "org_type": "公司", "target": "HER2, AXL", "modality": "bispecific ADC", "importance_level": "中", "total_score": 65.5, "institution_score": 65, "track_score": 90, "milestone_score": 40, "field_heat_score": 85, "bonus_score": 3, "brief_reason": "HER2×AXL双靶点bispecific ADC针对HER2异质性和AXL介导的耐药机制，采用eKiH平台和多种payload，仅处于preclinical阶段显示体外细胞毒性和异质性分析支持。机构为韩国专业ADC biotech（Dong-A ST子公司），非头部MNC但平台有一定认可，赛道为热门bispecific ADC+耐药克服，综合热度较高但开发阶段早期导致总分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5388", "id": "W57M_5wBZznHJdnt_W7P", "source_drug_name": "HER2xAXL BsAb", "title": "Dual targeting of HER2 and AXL by an eKiH-engineered bispecific ADC to overcome resistance in solid tumors", "abstract_text": "Background: AXL signaling is a key mediator of drug resistance, metastasis, and immune modulation in solid tumors. Its activation drives epithelial-mesenchymal transition (EMT) and promotes tumor aggressiveness, underscoring its role in therapeutic resistance.\nHER2, a clinically validated ADC target, is similarly associated with oncogenic signaling and metastatic progression. Dual targeting of HER2 and AXL offers a rational approach to suppress complementary resistance pathways and overcome tumor heterogeneity, particularly in patients refractory to standard therapies. We therefore developed a HER2×AXL bispecific ADC using Dong-A ST BsAb platform with an enhanced knob-into-hole (eKiH) interface to improve heavy-chain pairing fidelity and bispecific assembly.\nMethods: Lead HER2 and AXL antibodies were selected for high affinity and improved internalization; the AXL lead outperformed benchmark anti-AXL antibodies in binding and internalization assays. Bispecifics were assembled using Dong-A ST BsAb platform and site-selectively conjugated to monomethyl auristatin E (MMAE), exatecan (a topoisomerase-I inhibitor), or dual-payload configurations. Single-cell RNA-seq (scRNA-seq) datasets from lung, breast, and gastric cancers were analyzed to profile HER2 heterogeneity and AXL-associated epithelial-mesenchymal transition (EMT) signatures. Multiplex immunohistochemistry (mIHC) on tissue microarrays quantified spatial co-expression and heterogeneity. Combination potential with immune checkpoint inhibitors (ICIs) was explored via immune-correlative analyses and ongoing co-treatment studies.\nResults: scRNA-seq revealed pronounced intra- and inter-tumoral HER2 heterogeneity across indications, while AXL-high tumors exhibited elevated EMT-related markers. mIHC confirmed mosaic/cluster-type co-expression and heterogeneous distribution of HER2 and AXL across multiple tumor types. HER2xAXL BsAb retained high-affinity binding to both targets and efficient internalization, with preliminary in-vitro cytotoxicity observed in HER2-high, AXL-high, and co-expressing models using MMAE, exatecan, and dual-payload ADCs. Immune-correlative data support the mechanistic rationale for ICI combinations, and formal co-treatment evaluations are in progress.\nConclusions: HER2xAXL is a rationally engineered HER2×AXL bispecific ADC designed to mitigate target heterogeneity and therapy resistance. These preclinical data support investigation in HER2-expressing solid tumors—including lung, breast, and gastric cancers—particularly in patients who have failed standard first-/second-line regimens.", "source_company": "AbTis Co., Ltd", "source_org_type": "公司", "row_number": 279, "target_meta": "HER2,AXL", "MOA_meta": "抗体偶联药物"}, {"drug_name": "Nerviano Medical Sciences’ RAD51 inhibitors", "company": "Nerviano Medical Sciences", "org_type": "公司", "target": "RAD51", "modality": "inhibitor", "importance_level": "中", "total_score": 65.5, "institution_score": 65, "track_score": 85, "milestone_score": 45, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "靶向RAD51 PPI抑制剂，新型机制针对HR-proficient癌症，具有潜在first-in-class潜力，可与DNA损伤剂和DDR抑制剂联用。机构为意大利肿瘤研发公司，非头部MNC/biotech，preclinical阶段但显示口服生物利用度、单纳米摩尔生化活性及细胞抗增殖作用，赛道为热门DDR靶点但临床进展有限。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8832", "id": "QlXM_5wBX1NQZOEH-LK6", "source_drug_name": "Nerviano Medical Sciences’ RAD51 inhibitors", "title": "Highly potent inhibitors of RAD51, with first-in-class potential, targeting HR-proficient cancers", "abstract_text": "BACKGROUND: Targeting DNA repair pathways to selectively eliminate cancer cells has seen a huge success with multiple PARP1 inhibitors (PARPi) approved in different solid tumor indications. RAD51 is a key DNA repair gene with an important role in maintaining genomic stability by mediating homologous recombination repair (HRR) and promoting replication fork protection. Impairment of HRR reduces cell fitness in genetic backgrounds with high replication stress and sensitizes cancer cells to DNA-damaging agents and DNA Damage Response (DDR) inhibitors.\nMETHODS: A drug discovery campaign was conducted to identify novel small-molecule inhibitors of BRCA2-RAD51 protein-protein interaction (PPI). Structure-based drug design was employed to develop multiple compound series. Biochemical potency was assessed using a Fluorescence Polarization (FP) assay and an ATPase assay to measure the DNA-induced activity of RAD51, which is reliant on RAD51 self-oligomerization. A cellular reporter assay to measure HRR proficiency and a high content imaging assay to measure RAD51 foci formation were developed to assess compounds target engagement.\nRESULTS: We have identified proprietary RAD51 PPI inhibitors, orally bioavailable, demonstrating single-digit nanomolar biochemical potency on RAD51 and anti-proliferative activity in a subset of cancer cell lines. These include cell lines resistant to cisplatin or PARP1 inhibitors with a sensitivity profile distinct from RAD51 genetic depletion (based on the analysis of DepMap dataset). The anti-proliferative potency correlates with biochemical potency, cellular target engagement and activation of DNA damage response, confirming the expected on-target mechanism of action.\nCONCLUSIONS: The novel mechanism of action, with potential for combination with DNA damaging agents and DDR inhibitors, positions Nerviano Medical Sciences’ RAD51 inhibitors as promising first-in-class candidates for further development across multiple cancer types resistant to standard of care.", "source_company": "Nerviano Medical Sciences", "source_org_type": "公司", "row_number": 528, "target_meta": "RAD51", "MOA_meta": "抑制剂"}, {"drug_name": "15B6", "company": "National Institutes of Health", "org_type": "研究机构", "target": "mesothelin (非shed位点)", "modality": "bispecific antibody", "importance_level": "中", "total_score": 65.5, "institution_score": 45, "track_score": 85, "milestone_score": 70, "field_heat_score": 75, "bonus_score": 4, "brief_reason": "15B6为靶向mesothelin非shed膜近端位点的CD3双抗，可有效规避shed MSLN干扰，体外体外实验显示优于传统SS1双抗并诱导肿瘤完全消退。机构为NIH NCI得分中等，TCE+MSLN热门组合及抗shed设计带来较强赛道与bonus加分，整体临床前数据扎实但仍属早期阶段。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9646", "id": "sFXM_5wBX1NQZOEH-LS6", "source_drug_name": "15B6", "title": "A T-cell engager antibody targeting the non-shed site of mesothelin in solid tumors", "abstract_text": "Mesothelin (MSLN) is a cell surface protein that is overexpressed in various cancers, including mesothelioma, pancreatic, and ovarian cancer. Its expression in normal tissue is limited to the mesothelial cells lining the pleura, peritoneum and pericardium; make it an attractive target for antibody-based therapeutics. Many efforts have been dedicated towards the development of these antibody-based approaches but proteases in the tumor microenvironment promote the cleavage of MSLN from cancer cells. High concentrations of shed MSLN in the tumor microenvironment bind to the antibody inhibiting its activity and preventing the death of cancer cells.\nTo address the presence of shed MSLN, an antibody called 15B6 was designed. It binds the membrane-proximal, protease sensitive region of MSLN that is not shed in the tumor microenvironment. This study investigates the ability of 15B6-targeted bispecific antibodies to eliminate MSLN expressing cancers. We designed humanized and murine versions of a CD3x15B6 bispecific antibody, which binds the CD3 on T cells and the MSLN (15B6) epitope on cancer cells serving as a bridge to promote the activation of T cells to kill MSLN positive cancer cells. These 15B6-based antibodies were compared to SS1-based antibodies that target the distal N-terminal domain of MSLN that is shed by proteases. In-vitro, the SS1 and 15B6 antibodies hold similar cytotoxic activity, but when cocultured with MSLN 296-591, a recombinant protein mimicking shed MSLN, the SS1 antibodies activity is inhibited.\nIn-vivo, in a human mesothelioma model in immunodeficient mice, tumor shrinkage and growth inhibition were observed when treated with the 15B6-based antibody but not those treated with the SS1-based antibody. In an immunocompetent mouse model, the complete regression of colon and breast tumors was observed when treated with the 15B6-based antibody compared to the SS1 antibody and control samples. Transcriptional analysis revealed that 15B6-treated mice had higher levels of activation of both innate and adaptive immune cells, along with significant upregulation of cytokine and STAT5 signaling pathways. Through in-vitro and in-vivo studies, we have demonstrated that this 15B6-targeted antibody binds to the protease-sensitive region, is highly active against MSLN-expressing cancer cell lines in vitro, is not inhibited by shed MSLN, and promotes upregulation of immune cell populations and signaling pathways that support robust anti-tumor activity.", "source_company": "National Institutes of Health\nNational Cancer Institute, National Institutes of Health", "source_org_type": "研究机构", "row_number": 960, "target_meta": "MSLN", "MOA_meta": "双特异性抗体"}, {"drug_name": "c-MET × HER3 BsADC", "company": "OBI Pharma, Inc.", "org_type": "公司", "target": "c-MET × HER3", "modality": "BsADC", "importance_level": "中", "total_score": 65.5, "institution_score": 65, "track_score": 90, "milestone_score": 40, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "采用guide-effector机制的c-MET×HER3双特异性ADC，利用c-MET快速内化驱动HER3共内吞，提升低内化靶点载药递送和抗肿瘤活性。OBI Pharma为台湾临床阶段ADC专注biotech，在ADC领域获台湾最佳开发者认可，但该BsADC仍处preclinical/发现阶段，赛道热度高故综合中度重要。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5400", "id": "up3ECZ0B4z9FlvORyiZD", "source_drug_name": "c-MET × HER3 BsADC", "title": "Guide-effector bsADCs: Driving co-endocytosis for enhanced payload delivery", "abstract_text": "Bispecific antibodies (BsAbs) are engineered to simultaneously engage two distinct receptors, offering a powerful approach to enhance receptor internalization and intracellular payload delivery. By exploiting differences in endocytic capacities between receptors, dual targets can convert poorly internalizing target into efficiently internalized complexes—a mechanism particularly advantageous for bispecific antibody-drug conjugates (BsADCs).\nBsAbs targeting HER2×TROP2 and cMET×HER3 were engineered, expressed in ExpiCHO cells, and purified via Protein A affinity chromatography. BsADCs were conjugated by the glycan-based site-specific platform via a cleavable linker-payload system. The drug-antibody ratio (DAR) was determined per candidate. Internalization kinetics of BsAbs and their monospecific counterparts were assessed in receptor-coexpressing tumor cell lines (HER2/TROP2⁺ and cMET/HER3⁺) using a pH sensor dye. Upon antibody binding and internalization, the dye transitions from the neutral extracellular pH (7.4) to the acidic lysosomal environment (pH 4.5-5.5), resulting in increased fluorescence. Fluorescence signals were monitored in real time at 37 °C using a Cytation 5 imaging system.\nIn this study, the internalization of two BsAb pairs—HER2 × TROP2 and c-MET × HER3, was compared with their respective monospecific antibodies. Using a guide-effector mechanism, BsAbs pair a rapidly internalizing receptor (e.g., HER2 or c-MET) with a poorly internalizing one (e.g., TROP2 or HER3), leveraging the guide receptor’s endocytic capacity to drive co-endocytosis and lysosomal trafficking.\nHER2 × TROP2 BsADC (OBI-201) illustrates this concept: HER2 facilitates co-internalization of TROP2 (1.7-fold increase compared to the mono-ADC), enhancing lysosomal trafficking and intracellular payload delivery in tumors co-expressing both receptors, overcoming resistance seen with monospecific antibodies and improving cytotoxic efficacy. Similarly, c-MET × HER3 BsAbs exploit c-MET’s rapid internalization to drive HER3 uptake (5.5-fold increase compared to the HER3 mono-Ab), inducing receptor clustering, coordinated lysosomal trafficking, and increased intracellular payload delivery, thereby enhancing antitumor activity.\nThese findings show that BsAbs enhance receptor internalization via co-endocytosis, using a guide-effector mechanism to improve intracellular payload delivery and therapeutic potency. This strategy offers a generalizable approach for BsADC development, enabling targeting of low-expression or non-internalizing antigens and addressing resistant or heterogeneous tumors.", "source_company": "OBI Pharma, Inc.", "source_org_type": "公司", "row_number": 1200, "target_meta": "c-Met,HER3", "MOA_meta": "其他"}, {"drug_name": "the polymerase inhibitor", "company": "Pharmaron", "org_type": "公司", "target": "Polθ helicase domain", "modality": "inhibitor", "importance_level": "中", "total_score": 65.5, "institution_score": 45, "track_score": 85, "milestone_score": 75, "field_heat_score": 80, "bonus_score": 4, "brief_reason": "靶向Polθ helicase domain的抑制剂，在BRCA缺陷肿瘤中显示优于polymerase domain抑制剂的合成致死效应及与PARPi协同作用。公司为CRO服务机构而非原创新药公司，得分受限，但赛道热门（DNA修复新靶点+合成致死）、体外/体内数据较强且进入非GLP毒理。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6435", "id": "dZ7M_5wBZznHJdnt_W7P", "source_drug_name": "the polymerase inhibitor", "title": "In vitro and in vivo biology characterization of two novel inhibitors targeting the different domains of DNA polymerase theta (Polθ)", "abstract_text": "DNA polymerase theta (Polθ) is a 290 kD specialized and error-prone Polymerase A family enzyme that executes microhomology-mediated end joining (MMEJ), possessing an N-terminal helicase-like domain and a C-terminal DNA polymerase domain, which are linked by a large, unstructured central region. Polθ is normally expressed at low levels but is frequently overexpressed in tumours and is critical for the survival of homologous recombination (HR)-deficient cancer cells. Accordingly, Polθ has been proposed as an attractive therapeutic target for the treatment of BRCA deficient and DNA repair pathway defective cancers. Several inhibitors targeting either the polymerase or the helicase domain of Polθ have been described and progressed to the clinic. However, it is not clear which axis of intervention is the most beneficial even though inhibition of either domain elicits synthetic lethality with BRCA genes preclinically. Here we compare the in vitro biological profile of two novel Polθ inhibitors, one targeting the C-terminal DNA polymerase (Pol) domain and the other targeting the N-terminal helicase-like domain (Hel). Both inhibitors exhibit similar potency in their respective biochemical assays (Hel inhibitor IC50 = 2.1 nM, Pol inhibitor IC50 = 4.2 nM). However, in a colony formation cellular assay the Hel inhibitor elicited significantly stronger synthetic lethality in BRCA2-mutant tumour cells (Hel inhibitor IC50 = 2.1 nM; Pol inhibitor IC50 125.6 nM). Furthermore, this differentiation was evident mechanistically, where the Hel inhibitor inhibited MMEJ-mediated repair with a 3-fold higher potency and increased micronuclei formation in cells with a 200-fold higher potency when compared to the Pol inhibitor. When tested in vitro, in combination studies with the PARP inhibitor Niraparib, Hel showed a synergistic effect even at the lowest combination of concentrations tested (4 nM Hel, 15 nM Niraparib), whereas a 10-fold higher concentration of Pol inhibitor was needed to achieve the same synergistic effect. Based on its superior in vitro profile, the helicase inhibitor was progressed to BRCA1- and BRCA2-deficient xenograft models, where it evoked DNA damage and showed a dose-dependent sustained regression of tumour volume, in combination with a PARP inhibitor, even at the lowest dose tested of 3 mg/kg PO QD. The dose selection was based on the unbound exposure of the Hel inhibitor being in excess of the unbound cellular IC50 during the treatment period. Given the tumour regressive effects in vivo and favourable ADME profile in preclinical species and early human dose predictions, the helicase compound is currently undergoing evaluation in non-GLP toxicology studies.", "source_company": "Pharmaron", "source_org_type": "公司", "row_number": 1201, "target_meta": "POLQ", "MOA_meta": "抑制剂"}, {"drug_name": "B836", "company": "Nanolattix", "org_type": "公司", "target": "HER2 和 Tissue Factor (TF)", "modality": "bispecific ADC", "importance_level": "中", "total_score": 65.5, "institution_score": 45, "track_score": 90, "milestone_score": 70, "field_heat_score": 85, "bonus_score": 3, "brief_reason": "B836为靶向HER2和TF的双特异性ADC，旨在克服HER2 ADC如Enhertu的耐药性，采用热门双特异ADC赛道和双靶点设计。Nanolattix为国内新兴biotech，preclinical数据较强包括优于Enhertu的动物疗效和GLP猴安全性，支持临床推进。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5027", "id": "Up7ECZ0BZznHJdntvNYd", "source_drug_name": "B836", "title": "B836: A novel bispecific antibody-drug conjugate (ADC) as a clinical candidate to overcome trastuzumab deruxtecan resistance", "abstract_text": "Resistance to single-antigen HER2-targeted ADCs, such as Enhertu (trastuzumab deruxtecan, DS-8201) and Kadcyla (trastuzumab emtansine, T-DM1), poses a significant challenge in HER2-positive cancers, often due to tumor heterogeneity and antigen downregulation. To address this unmet medical need, we developed B836, a first-in-class bispecific ADC leveraging the Nanolattix Biolattix technology platform. B836 is engineered to target both HER2 and Tissue Factor (TF). TF is an attractive therapeutic target and is overexpressed in various tumor types. Results from in vitro experiments demonstrated that B836 achieved significantly enhanced cancer cell binding and internalization compared to single-target ADCs. In vivo studies of B836 showed superior anti-tumor efficacy over Enhertu, particularly in animal models characterized by low HER2 expression, suggesting its potential for overcoming primary or acquired resistance mechanisms. GLP safety and toxicokinetic (TK) studies were conducted in cynomolgus monkeys. No drug-related ocular toxicity or abnormalities in body temperature, blood pressure, or electrocardiogram (ECG) were observed. Furthermore, no systemic toxicity was detected at doses up to 5 mg/kg. These collective findings support the continued clinical development of B836, promising therapeutic potential in oncology.", "source_company": "Nanolattix", "source_org_type": "公司", "row_number": 1249, "target_meta": "HER2,tissue factor", "MOA_meta": "抗体偶联药物"}, {"drug_name": "MAb52-4.2-ADC (MedAbome)", "company": "MedAbome, Inc.", "org_type": "公司", "target": "SLC3A2", "modality": "ADC", "importance_level": "中", "total_score": 65.5, "institution_score": 55, "track_score": 80, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "靶向SLC3A2（CD98hc）的first-in-class ADC，肿瘤细胞高表达且正常组织低表达，机制为选择性识别肿瘤相关构象表位并高效内化递送MMAE。机构为美国preclinical-stage小型biotech非头部，得分一般；ADC赛道热门但SLC3A2靶点非顶级热门，preclinical阶段有CDX肿瘤完全消退及初步毒理安全数据，支持中度重要性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4325", "id": "X57M_5wBZznHJdnt_W3O", "source_drug_name": "MAb52-4.2-ADC (MedAbome)", "title": "Preclinical efficacy of a first-in-class anti-SLC3A2 ADC in hard-to-treat solid and hematologic malignancies", "abstract_text": "SLC3A2 (CD98 heavy chain, CD98hc, or 4F2hc) is a type II transmembrane glycoprotein that functions primarily as the heavy chain component of heterodimeric amino acid transporters (HATs). The aberrant overexpression of SLC3A2 has been linked to many types of cancer, such as lung cancer, breast cancer, colorectal cancer (CRC), pancreatic cancer (PDAC), and various types of hematologic malignancies. Using our proprietary live-cell immunization (LC-I) and high-throughput screening (LC-HTS) platforms, we developed MAb52-4.2, an anti-SLC3A2 monoclonal antibody that selectively recognizes a tumor-associated conformational epitope of SLC3A2, which significantly elevated expression levels in cancer cell lines, and exhibits minimal or no cross-reactivity with normal cells or tissues. Both the chimeric and humanized versions of MAb52-4.2 bound to recombinant SLC3A2-ECD with high affinities in the low single-digit nanomolar range. MAb52-4.2 cAb, containing two Fc point-mutations, was conjugated to MMAE through an MC-Vc-PAB linker to produce MAb52-4.2-ADC (DAR4). MAb52-4.2-ADC demonstrated potent antiproliferative effects in vitro, with cytotoxicity correlating with the target abundance and antibody internalization efficiency across a variety of cancer cell lines. A single intraperitoneal (i.p.) dose of MAb52-4.2-ADC at 4, 7, or 10 mg/kg effectively inhibited tumor growth in cell line-derived xenograft (CDX) mouse models of triple-negative breast cancer (TNBC), non-small cell lung cancer (NSCLC), gastric cancer (GC), and other tumor types, with subcutaneously inoculated tumors completely regressing within 24~30 days post-treatment. Preliminary toxicology studies indicated that MAb52-4.2-ADC did not raise any safety concerns. These findings support MAb52-4.2-ADC as a promising therapeutic candidate for treating solid and hematologic malignancies, and potentially mitigating toxicity concerns. Ongoing studies aiming to support further clinical investigation include MAb52-4.2-ADC in patient-derived xenograft (PDX) gastrointestinal (GI) cancer models, along with retrospective analyses of its target expression in clinical tumor samples.", "source_company": "MedAbome, Inc.", "source_org_type": "公司", "row_number": 1256, "target_meta": "SLC3A2", "MOA_meta": "抗体偶联药物"}, {"drug_name": "modified p53 neo-epitope peptides", "company": "Sequencio Therapeutics", "org_type": "公司", "target": "p53 neoantigen", "modality": "other", "importance_level": "中", "total_score": 65.3, "institution_score": 65, "track_score": 80, "milestone_score": 50, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "针对p53新抗原的修饰表位肽，通过AI优化单氨基酸替换提升免疫原性，在人源化小鼠模型中诱导强CD8+ T细胞应答。公司为2026年新成立的中国香港CK Life Sciences全资子公司，赛道为neoantigen疫苗热门但处于preclinical早期，数据初步积极。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3636", "id": "1Z7M_5wBZznHJdnt_W3O", "source_drug_name": "modified p53 neo-epitope peptides", "title": "Single amino acid residue substitution to improve immunogenicity of HLA peptides targeting p53 neoantigen", "abstract_text": "Background and objective: p53 tumor suppressor gene is frequently mutated in human cancer, which is highly associated with advance malignancy development and poor prognosis. However, there are no effective treatments targeting p53 expressed by mutant p53. Aiming at developing therapeutic vaccines targeting mutant p53, we coupled amino acid residue substitution and HLA peptide prediction using an AI model that we developed. Previously, we reported that modified HLA-A*02:01-specific peptides designed using our approach demonstrated significant immunogenicity in a HLA-A*02:01-humanized mouse model. Here, we further designed modified p53 neo-epitopes specific to HLA-A*03:01 and HLA-A*11:01 using this approach and studied their immunogenicity in HLA-humanized mice.\nMethods: The AI model was used to analyze common p53 neoantigens and predict epitopes for HLA-A*03:01 and HLA-A*11:01. The epitopes underwent computer-assisted saturation mutagenesis that simulated single amino acid substitution to obtain the associated presentation score changes. Peptide sequences with improved presentation scores were synthesized. The binding affinity with HLA was determined using surface plasmon resonance (SPR). The immunogenicity was determined by IFNγ ELISpot assay and intracellular cytokine staining (ICS) using splenocytes collected from mice vaccinated with the peptides.\nResults: Modified p53 neo-epitopes were analyzed by our AI model after saturation mutagenesis, and twelve of the modified neo-epitopes with at least 5% increase of presentation probability were selected for experimental analyses. Most of these peptides demonstrated high binding affinity with HLA-A*03:01 or HLA-A*11:01 and β2-microglobulin heterodimer as characterized by SPR. Using splenocytes collected from HLA-A*03:01 or HLA-A*11:01-humanized mice vaccinated with pools of these peptides, IFNγ ELISpot assay and IFNγ ICS revealed that all HLA-A*03:01 peptides and 9 out of 10 HLA-A*11:01 peptides effectively induced CD8+ T-cell response. Remarkably, challenging the splenocytes with the respective native neoantigen peptides reactivated the cellular immunity induced by most of AI-designed modified peptides, suggesting that immunization of the AI-designed modified peptides induced CD8+ T-cell response against the native p53 neoantigens.\nConclusion: We have designed multiple peptides derived from common p53 neoantigens and demonstrated that they are strongly immunogenic in HLA-A*02:01, HLA-A*03:01 and HLA-A*11:01 background. These findings further support that the coupling of MHC-I presentation prediction AI model and computer assisted saturation mutagenesis is promising in modifying neo-epitopes to improve anti-tumor immunity via the CD8+ T-cell response.", "source_company": "Sequencio Therapeutics", "source_org_type": "公司", "row_number": 1104, "target_meta": "p53", "MOA_meta": "其他"}, {"drug_name": "GRX2672", "company": "Guardian Therapeutics", "org_type": "公司", "target": "LRRC15", "modality": "ApDC", "importance_level": "中", "total_score": 65, "institution_score": 55, "track_score": 75, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "GRX2672为靶向LRRC15的aptamer-drug conjugate (ApDC)，利用小分子大小优势实现深层肿瘤渗透并完全抑制肿瘤生长。机构为专注aptamer的中小型biotech，非头部公司但有一定创新；ApDC+LRRC15赛道有一定热度但非最热门，preclinical阶段显示强效无毒性，支持中等重要性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4316", "id": "ilXM_5wBX1NQZOEH-LG6", "source_drug_name": "GRX2672", "title": "Targeting LRRC15 with an aptamer-drug conjugate achieves complete tumor growth inhibition", "abstract_text": "Antibody-drug conjugates (ADCs) have demonstrated the clinical potential of targeted payload delivery for cancer therapy. However, their large molecular size can limit tumor penetration, leaving regions of the tumor insufficiently exposed to the cytotoxic payload. To address this limitation, GRX2672 has been developed as a novel aptamer-drug conjugate (ApDC) designed to target LRRC15-expressing tumors while maintaining a small molecular size to enable deep tumor penetration. LRRC15 (leucine-rich repeat-containing protein 15) is a transmembrane member of the LRR superfamily involved in cell-cell and cell-matrix interactions. It is highly expressed in mesenchymal-derived tumors such as sarcoma, glioblastoma, and melanoma, making it an attractive target for therapeutic intervention. Aptamers are short, structured oligonucleotides that bind their targets with high affinity and specificity. Compared with monoclonal antibodies, their compact size enables superior tissue and tumor penetration. Moreover, aptamers can be engineered to neutralize oncogenic targets, deliver cytotoxic payloads, or achieve both simultaneously. Incorporating a proprietary half-life-extension moiety preserves the aptamer’s small size and tumor-penetrating capability while markedly improving its pharmacokinetic properties. Here, we describe an LRRC15-targeting aptamer with high affinity and selectivity that has been conjugated to 2DAR of a novel topoisomerase I inhibitor (PBX-7016) at the 5′ end and a half-life-extending fatty acid at the 3′ end. The resulting ApDC, GRX2672, selectively kills LRRC15-positive cells in vitro and achieves complete tumor growth inhibition in vivo without observed toxicity. These findings support the potential of LRRC15-targeted ApDCs as an emerging therapeutic strategy to improve outcomes for patients with LRRC15-positive tumors.", "source_company": "Guardian Therapeutics", "source_org_type": "公司", "row_number": 184, "target_meta": "LRRC15", "MOA_meta": "其他"}, {"drug_name": "LIME", "company": "Dana-Farber Cancer Institute", "org_type": "医院", "target": "未披露", "modality": "other", "importance_level": "中", "total_score": 64.5, "institution_score": 45, "track_score": 85, "milestone_score": 75, "field_heat_score": 80, "bonus_score": 8, "brief_reason": "LIME为工程化非致病E. coli表面共展示肿瘤抗原和效应细胞受体scFvs的活细菌免疫衔接平台，实现局部免疫桥接和新机制肿瘤浸润，无明确单一靶点。机构为顶级癌症研究医院但非药企导致机构分较低，细菌递送+免疫衔接的创新热门赛道及优于Tarlatamab的动物数据+无CRS亮点使赛道和里程碑分较高，总分处于中位。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/7527", "id": "F1XM_5wBX1NQZOEH-LK6", "source_drug_name": "LIME", "title": "Reprogramming of the non-pathogenic E. coli surface architecture to create next-generation immune engagers for potent cancer therapies", "abstract_text": "Background: Multi-specific immune engagers show therapeutic promise but are limited by systemic toxicities (e.g., cytokine release syndrome, CRS), short half-lives, and poor infiltration into the immunosuppressive tumor microenvironment (TME). Tumor-homing bacteria offer a targeted delivery strategy capable of overcoming restricted infiltration and TME-mediated suppression. Building on our E. coli K-12 surface display platform for localized cytokine delivery (Yang et al., Nat Biotechnol, 2024), we developed Live Immune Modulating Engagers (LIME), engineered E. coli co-displaying scFvs against tumor-associated antigens and effector-cell receptors (T or NK). We hypothesize that dual-display LIME enhances anti-tumor immunity by enabling localized effector-cell activation and precise tumor-immune cell bridging.\nMethods: E. coli was engineered to display scFvs targeting TAAs (CD19, Mesothelin, DLL3, etc.) and immune receptors (CD3, NKG2D, etc.) using optimized outer-membrane scaffolds, confirmed by flow cytometry. In vitro co-cultures with primary human T or NK cells assessed binding, activation (CD25/CD69), and cytotoxicity (7-AAD/Annexin V). In syngeneic A20 and KPC tumor models, mice received intravenous LIME ± anti-PD-1 (i.p.) or RMC-7977 (oral). In DLL3⁺ H69 xenografts, NSG mice were infused with human CD3⁺ T cells followed by LIME, benchmarked against the FDA-approved engager Tarlatamab. Tumor growth was monitored and analyzed by flow cytometry, multiplex ELISA, and CFU quantification.\nResults: In vitro, LIME activated T or NK cells and enhanced killing across a broad panel of tumor cell lines, including Small cell lung cancer, Glioblastoma, Pancreatic ductal adenocarcinoma, etc. In vivo, CD19 LIME cured ~34% of A20-bearing mice and achieved ~80% cures when combined with anti-PD-1, generating durable immune memory. Mesothelin LIME significantly inhibited KPC tumor progression, with extended survival upon RMC-7977 co-treatment. DLL3 LIME provided superior tumor control compared with Tarlatamab in H69 xenografts. Mechanistically, LIME reprogrammed the TME by activating T and NK cells, driving macrophage repolarization toward an M1 state, and enhancing DC activation in draining lymph nodes. Bacteria remained enriched in tumors, and no evidence of CRS was observed in plasma.\nConclusions: LIME represents a versatile platform that enables localized, immune engagement, overcomes major barriers in solid tumors, and outperforms existing immune engagers while maintaining a favorable safety profile.", "source_company": "Dana-Farber Cancer Institute", "source_org_type": "医院", "row_number": 22, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "CAR-T cell therapy", "company": "University of Pennsylvania", "org_type": "大学", "target": "未披露", "modality": "CAR", "importance_level": "中", "total_score": 64.5, "institution_score": 65, "track_score": 95, "milestone_score": 30, "field_heat_score": 85, "bonus_score": 0, "brief_reason": "该项目聚焦in vivo CAR-T生成技术，这是当前细胞治疗领域极热门赛道，但摘要无任何具体内容、无披露靶点、无开发阶段信息。机构为CAR-T发源地大学但非商业公司，preclinical强度未知导致里程碑分较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/769", "id": "olXM_5wBX1NQZOEH-LK6", "source_drug_name": "CAR-T cell therapy", "title": "Towards in vivo CART", "abstract_text": "There is no abstract associated with this presentation.", "source_company": "University of Pennsylvania", "source_org_type": "大学", "row_number": 43, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "VOR-101", "company": "Voro Therapeutics", "org_type": "公司", "target": "CD47", "modality": "inhibitor", "importance_level": "中", "total_score": 64.5, "institution_score": 45, "track_score": 85, "milestone_score": 70, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "VOR-101为肿瘤微环境激活的masked高亲和力CD47 blocker，可克服CD47广泛表达导致的系统毒性，实现更好疗效窗。机构为早期初创biotech（仅种子轮250万美元融资），但PrimeBody平台创新性强、CD47 masked策略热度高、preclinical数据优秀（>700倍选择性、异种移植模型持久完全缓解、IND-enabling阶段），故综合打分为中偏高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4298", "id": "lFXM_5wBX1NQZOEH-LG6", "source_drug_name": "VOR-101", "title": "Tumor-activated PrimeBody biologics platform enables more potent CD47 targeting and superior therapeutic index in preclinical models", "abstract_text": "Systemic toxicities and dose-exposure limitations caused by target expression on normal tissues remain major barriers to effective cancer therapy. Tumor-activated masked biologics are a promising strategy to improve safety and efficacy, as highlighted by evolving clinical data with masked T-cell engagers (TCEs) and masked antibody-drug conjugates (ADCs). However, an optimized platform that balances protease specificity, systemic stability, and tumor release kinetics across diverse tumor types is lacking.VORO’s PrimeBody biologics platform employs novel activation linkers that are rapidly cleaved in the tumor microenvironment but are stable in normal tissues, demonstrating substantially improved tumor-selectivity compared to clinical benchmarks. These linkers are coupled with novel, finely tuned affinity-based masking domains to precisely control target affinity and tumor-specific release kinetics. PrimeBody masking is ideal for novel, more potent CD47-targeted biologics to overcome safety limitations caused by ubiquitous CD47 expression in healthy tissues and simultaneously enable enhanced anti-tumor efficacy.VOR-101 is a masked, Fc-enhanced, high-affinity CD47 blocker that remains a latent prodrug until it is activated by proteolytic cleavage in the tumor microenvironment. In vitro, unmasked VOR-101 drives potent phagocytosis (EC₅₀ ~20 pM) by primary human macrophages against epithelial cancer cell lines (DLD-1, HCT116, HT29, MCF-7, CAL27), while masked VOR-101 is inert (>2,000-fold higher EC₅₀). Ex vivo, VOR-101 is rapidly activated by human tumor surgical samples across all tested tumor types yet remains stable and intact in serum from healthy volunteers, cancer patients, and non-human primates for >14 days. In contrast, identical constructs engineered with clinical benchmark linkers exhibited significantly slower tumor activation and rapid serum degradation. Consequently, VOR-101 achieves >700-fold tumor-to-serum selectivity, a major improvement over the <25-fold selectivity observed with benchmark linkers currently in clinical development.In a translational hCD47/hSIRPα mouse model, magrolimab induced 50-60% depletion of red blood cells (RBCs) and exhibited poor systemic exposure (~10 nM). By contrast, VOR-101 at equimolar dosing achieved ~1 µM blood concentrations (~100-fold higher systemic concentration) while maintaining normal RBC counts. In xenograft models, VOR-101 induced durable complete responses that persisted well beyond the dosing period.Together, these findings demonstrate that VOR-101 (a tumor-activated, Fc-enhanced, high-affinity CD47 blocker) significantly improves the therapeutic index in preclinical models compared to clinical comparators. VOR-101 is advancing through IND-enabling studies with potential to exhibit single-agent activity in solid tumors.", "source_company": "Voro Therapeutics", "source_org_type": "公司", "row_number": 187, "target_meta": "CD47", "MOA_meta": "抑制剂"}, {"drug_name": "YB-811", "company": "Ymmunobio AG", "org_type": "公司", "target": "NPTXR", "modality": "ADC", "importance_level": "中", "total_score": 64.5, "institution_score": 55, "track_score": 85, "milestone_score": 50, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "YB-811为靶向肿瘤特异性NPTXR的新型双负载ADC，在多种实体瘤中高表达且正常组织无表达，展示显著肿瘤生长抑制/消退的preclinical疗效；Ymmunobio为小型preclinical阶段欧洲biotech，NPTXR为first-in-class靶点+ADC热门赛道加持，但公司规模与开发阶段限制总体评分。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5432", "id": "lp7M_5wBZznHJdnt_W7P", "source_drug_name": "YB-811", "title": "YB-811, a novel antibody drug conjugate targeting the tumor-selective human neuronal pentraxin receptor shows pronounced efficacy in experimental tumor models", "abstract_text": "The human neuronal pentraxin receptor (NPTXR) gene encodes a type II transmembrane protein that functions as a trans-synaptic organizer and anchors neuronal pentraxin complexes to plasma membranes in a subset of neuronal cells of the hippocampus and cerebral cortex. Beside its synaptic functions in the brain, NPTXR is not present in other organs and therefore does not have any physiological role; hence NPTXR−/−mice showed no abnormalities in reproduction, development, metabolism, or motor function. Recent immunohistochemistry studies performed with a fully humanized monoclonal antibody (YB-800) targeting NPTXR with high affinity have revealed expression of membrane-associated NPTXR protein in a wide variety of solid tumors (but not in adjacent healthy tissues and healthy tissue samples) with a high prevalence (up to 98%) and H-scores (up to 300); e.g., in bladder, cervix, non-TNBC, NSCLC, and pancreas tumor samples. These results strongly support the rationale for the design of a YB-800-based antibody drug conjugate (ADC) as novel option for safe therapeutic intervention in Oncology. A novel ADC (YB-811) was engineered with YB-800 linked to 4 monomethylauristatin F molecules (via non-cleavable linkers), and 4 exatecan molecules (via cleavable linkers). YB-811 was evaluated in multiple experimental tumor models in both cell-based assays and in vivo tumor studies. Results clearly indicate concentration- and time-dependent effect on tumor cell proliferation and survival, as well as pronounced anti-tumor activity - tumor growth inhibition/regression - in established tumor-bearing athymic mice. Taken together, these results strongly support further exploration of the potential therapeutic benefit of YB-811.", "source_company": "Ymmunobio AG", "source_org_type": "公司", "row_number": 281, "target_meta": "NPTXR", "MOA_meta": "抗体偶联药物"}, {"drug_name": "bi- and tri-specific ADCs targeting MUC1* and HER2 or alpha-v-beta-6", "company": "Minerva Biotechnologies", "org_type": "公司", "target": "MUC1* (and HER2 or alpha-v-beta-6)", "modality": "ADC", "importance_level": "中", "total_score": 64.5, "institution_score": 45, "track_score": 85, "milestone_score": 70, "field_heat_score": 75, "bonus_score": 5, "brief_reason": "靶向癌细胞特异性生长因子受体MUC1*的双/三特异性ADC，联合HER2或αvβ6克服耐药和复发。Minerva为专注MUC1*的中小型biotech，ADC赛道+克服HER2耐药机制热度高，动物模型及linker-payload优于Deruxtecan，但整体仍处preclinical。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4477", "id": "D1XM_5wBX1NQZOEH-LK6", "source_drug_name": "bi- and tri-specific ADCs targeting MUC1* and HER2 or alpha-v-beta-6", "title": "Bi- and tri-specific ADCs that target two distinct growth factor receptor forms of MUC1* and HER2 or alpha-v-beta-6 inhibit tumor recurrence and overcome acquired resistance", "abstract_text": "Purpose: Develop more effective cancer therapeutics by simultaneously targeting multiple drivers of growth, metastasis and resistance.\nMethods: MUC1 is aberrantly expressed on over 75% of solid tumor cancers. Although cloned 30 years ago, there is still no approved MUC1-targeted drug. Previous attempts, including those targeting trapped glycans, targeted the tandem repeat domain, which is shed after cleavage by cancer-associated enzymes. MUC1* with a 45-amino acid ecd (extracellular domain) is the only form that has been shown to function as a growth factor receptor via dimerization of ecd by embryonic growth factors. We show that where MUC1 is cleaved determines the conformation of the remaining ecd. Even within a truncated 45-amino acid ecd, there are distinct conformations that only exist on cancer cells and others that are only on progenitor cells. All these species have been mistakenly grouped together as “MUC1-C”. We developed monoclonal antibodies that specifically bind to each conformation and mapped their expression on cancer vs normal tissues vs progenitor cells. We then generated bi- and tri-specific ADCs that simultaneously bind to 2 or 3 cancer targets.\nResults: Data show there are 2 distinct MUC1* receptors that drive tumor growth and metastasis. Targeting one and not the other led to tumor recurrence. We developed bi- and tri-specific antibodies that simultaneously bind to both MUC1* growth factor receptors, and HER2 or alpha-v-beta-6. In antibody internalization experiments, multi-specific antibodies were internalized faster and more completely than mono-specifics. In ADC format, bi-specific antibodies that hit both MUC1* growth factor receptors inhibited tumor recurrence in animals. ADCs incorporating both a MUC1* antibody and Trastuzumab killed Trastuzumab-resistant cancer cells with an IC50 of 0.05 nM compared to 0.73 nM on Trastuzumab sensitive parent cells. Indeed, in Phase I huMNC2-CAR44 trial, patients who had acquired resistance to Trastuzumab or Fam-Trastuzumab Deruxtecan-nxki were best responders in our trial with 75% DCR, 11-month OS, 11.3 month increased survival in patients with high MUC1* expression. In animals, our novel linker payload out-performed industry gold standard Deruxtecan.\nConclusions: It is critical that MUC1-targeted therapeutics hit the cancer-specific forms of MUC1*. Therapeutics that incorporate antibodies that bind to hematopoietic stem cells, for example, would be disastrous if given to cancer patients. Therapeutics that target full-length MUC1, whether aberrantly glycosylated or not, could give initial positive responses via ADC bystander killing. However, the hypothesis is that by killing cells expressing full-length MUC1, which plays no role in cell growth, the MUC1*-positive cell population would be enriched and would accelerate tumor growth and metastasis.", "source_company": "Minerva Biotechnologies", "source_org_type": "公司", "row_number": 501, "target_meta": "MUC1,HER2,αvβ6", "MOA_meta": "抗体偶联药物"}, {"drug_name": "JWZ-8-103", "company": "Stanford Cancer Institute", "org_type": "研究机构", "target": "TRIM21", "modality": "molecular glue", "importance_level": "中", "total_score": 64.5, "institution_score": 35, "track_score": 90, "milestone_score": 75, "field_heat_score": 85, "bonus_score": 8, "brief_reason": "JWZ-8-103为TRIM21分子胶，通过诱导核孔复合体（NPC）降解展现抗PDAC等实体瘤活性。机构为学术研究机构得分较低，但分子胶+新型NPC靶向机制极具创新性和热门赛道价值，preclinical数据扎实且具转化潜力。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/2046", "id": "pVXM_5wBX1NQZOEH-LK6", "source_drug_name": "JWZ-8-103", "title": "Discovery of TRIM21 molecular glues that drive potent anti-tumor efficacy via nuclear pore complex degradation", "abstract_text": "Cancer cells are acutely dependent on nuclear transport due to elevated transcriptional activity, suggesting a therapeutic opportunity for inhibition of the nuclear pore complex (NPC). Through a combination of large-scale phenotypic profiling, genome-scale functional genomics, and mass spectrometry-based proteomics, we discovered that the clinical drug PRLX-93936 (PRLX) is a molecular glue that binds and reprograms the TRIM21 E3 ubiquitin ligase to degrade the NPC, resulting in potent inhibition of pancreatic ductal adenocarcinoma (PDAC) cells.\n\tPRLX, an optimized derivative of erastin, was previously tested in phase 1 trials with modest activity. Importantly, unlike erastin, PRLX induced apoptosis rather than ferroptosis via an unknown molecular target. To identify sensitive cancer models, we profiled PRLX against ~900 cell lines using the PRISM barcoded screening approach, which demonstrated lineage-specific activity against PDAC and head and neck cancers. This activity strongly correlated with high mRNA expression of the TRIM21 E3 ligase. Next, we conducted genome-scale CRISPR/Cas9 knockout and activation screens, which revealed TRIM21 as the top functional mediator of PRLX response across the entire genome. TRIM21 knockout conferred complete resistance to PRLX, while TRIM21 overexpression was sufficient to sensitize cells to the drug.\n\tGiven the strong functional evidence, we hypothesized that TRIM21 is the direct molecular target of PRLX. TRIM21 is a cytosolic antibody receptor known for its role in degrading intracellular pathogens. We first performed a tiled mutagenesis screen of the TRIM21 gene, which identified multiple mutations clustering at a putative binding pocket in the PRYSPRY substrate recognition domain. We then confirmed direct compound binding to the recombinant TRIM21 PRYSPRY domain via surface plasmon resonance (SPR).\n\tSince TRIM21 is a ubiquitin ligase, we sought to identify its potential neo-substrates upon compound treatment. We performed extensive proteomic profiling to evaluate changes in protein abundance, ubiquitination, and TRIM21 proximity labeling. All three methods unexpectedly identified nuclear pore complex proteins as the top hits. Re-analysis of our CRISPR knockout screen data revealed that a single guide RNA (out of four) against NUP98 conferred strong resistance. This active guide uniquely targeted the NUP98 autoproteolytic domain (APD) and yielded complete resistance to PRLX. Using multiple orthogonal assays (NanoBiT, TR-FRET, and SPR), we demonstrated that the compound acts as a molecular glue to induce physical proximity between TRIM21 and NUP98.\n\tThis molecular glue mechanism is highly effective against cancer because, as prior work shows, cancer cells undergo apoptosis upon NPC disruption while normal cells can recover. We confirmed this selective vulnerability. Compound treatment led to a loss of short-lived pro-survival mRNAs in cancer cells (by qPCR and RNAscope), and live-cell imaging showed that while the proliferation of non-malignant cells was slowed, PDAC cells underwent rapid and irreversible cell death. These findings support a model where temporary, TRIM21-mediated NPC degradation creates a therapeutic window by preferentially inducing cancer cell death.\n\tUsing PRLX as a starting point, phenotype-guided medicinal chemistry optimization yielded novel compounds with >10-fold greater potency, improved drug-like properties, and robust oral bioavailability. An improved derivative, JWZ-8-103, was successfully co-crystallized with the TRIM21 PRYSPRY domain, structurally confirming the binding mode and enabling further optimization. To establish translational potential, we employed patient-derived PDAC organoids and in vivo models. Prospectively selecting organoids based on TRIM21 expression confirmed its potential as a predictive biomarker of compound efficacy. Furthermore, optimized compounds demonstrated robust anti-PDAC efficacy in vivo against multiple KRAS-mutant xenograft models.\n\tIn summary, our work demonstrates the power of unbiased phenotypic screening to uncover novel cancer biology and develop targeted therapeutics. We have discovered potent, orally bioavailable TRIM21 molecular glues that degrade the NPC, validated a predictive biomarker, and established a strong therapeutic rationale and preclinical efficacy for their use in solid tumors. Ongoing work is focused on developing compounds with enhanced potency, evaluating drug combinations, and performing preclinical toxicology studies. The discovery of TRIM21-mediated NPC degraders presents an unexpected and promising new strategy for the treatment of PDAC and other challenging solid tumors.", "source_company": "Stanford Cancer Institute", "source_org_type": "研究机构", "row_number": 591, "target_meta": "TRIM21", "MOA_meta": "分子胶"}, {"drug_name": "CD8 nanobody-targeted lipid nanoparticles encapsulating CD13 nanoCAR circular RNAs", "company": "Citil Pharma", "org_type": "公司", "target": "CD13", "modality": "other", "importance_level": "中", "total_score": 64.5, "institution_score": 45, "track_score": 85, "milestone_score": 65, "field_heat_score": 75, "bonus_score": 5, "brief_reason": "采用CD8 nanobody靶向的脂质纳米粒递送CD13 nanoCAR circRNA，实现原位生成CAR-T细胞靶向CD13治疗AML，机制创新且针对异质性肿瘤。Citil Pharma为小型biotech，preclinical阶段在小鼠模型显示有效杀伤肿瘤但非临床级里程碑，热门赛道in situ CAR-T+circRNA+nanobody加分但整体开发早期。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5218", "id": "-lXM_5wBX1NQZOEH-LK6", "source_drug_name": "CD8 nanobody-targeted lipid nanoparticles encapsulating CD13 nanoCAR circular RNAs", "title": "CD8 nanobody-targeted lipid nanoparticles encapsulating CD13 nanoCAR circular RNAs for in situ CAR-T cell eradication of acute myeloid leukemia", "abstract_text": "Acute myeloid leukemia (AML) is an aggressive and recurrent cancer with a high mortality rate. Chimeric antigen receptor (CAR)-T cell therapy is an FDA approved therapy for acute lymphoblastic leukemia (ALL) but not for AML mainly due to hematopoietic stem and progenitor cell side effects. This is driven by persistent CD13, CD33, CD123 targeting from lentivirus-transduced CAR-T cells. Yet, CD13, a prognostic marker for AML, identifies 95% of the AML blasts and most leukemic stem cells (LSCs). AML is also a heterogenous cancer with diverse antigen profiles, posing treatment challenges. Finally, current CAR-T cell therapies are immensely costly due to cumbersome ex vivo T cell and viral procedures, restricting patient access.\nWe aim to overcome these technical challenges by leveraging the low tonic signaling of VHH-based nanobodies, transient expression of circular RNAs (circRNAs), and non-viral properties of lipid nanoparticles for effective eradication of AML while minimizing negative hematopoietic effects. Specifically, we attached CD8 nanobodies to lipid nanoparticles, constructed CD13 nanoCARs on circRNA backbones, and assembled the targeted circRNA lipid nanoparticle complexes. These complexes enable in situ, cell-specific engineering of splenic human CD8+ T cells and generate cytotoxic CD13 nanoCAR-T cells that target the prevalent AML population.\nWe demonstrated the feasibility of this approach by generating a CD8 nanobody with 86% reactivity toward human CD8+ T cells. We then customized the CD8 nanobody with a negatively charged polyglutamic acid tail to form strong electrostatic associations with our positively charged, proprietary lipid nanoparticles. We produced CD13 nanoCAR circRNAs with undetectable levels of double-stranded RNA impurities through cellulose purification and encapsulated them in the lipid nanoparticles by microfluidic mixing. The entire targeted circRNA lipid nanoparticle complex selectively transfected 24% of the human CD3+ lymphoid T cells in the spleen of NPG mice previously reconstituted with human PBMCs. We then assayed and selected the THP-1 human AML cell line showing high CD13 expression and low nonspecific T cell killing in vitro. In an immunodeficient NPG CDX mouse model, CD8 nanobody-targeted lipid nanoparticles encapsulating CD13 nanoCAR circRNAs exhibit specific and effective in vivo killing of a subcutaneously engrafted THP-1 tumor.", "source_company": "Citil Pharma", "source_org_type": "公司", "row_number": 650, "target_meta": "ANPEP", "MOA_meta": "其他"}, {"drug_name": "GS002", "company": "Shanghai Ginspire Biologics Co., Ltd", "org_type": "公司", "target": "PD-L1", "modality": "ADC", "importance_level": "中", "total_score": 64.5, "institution_score": 45, "track_score": 85, "milestone_score": 70, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "GS002是一款靶向PD-L1的ADC，结合免疫检查点抑制和靶向细胞毒递送，双机制协同作用，linker-payload优化优于DXd，展现优异溶解度、稳定性和旁观者杀伤。机构为上海小型biotech非头部，赛道ADC+PD-L1热门但preclinical阶段，综合潜力中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5381", "id": "U1XM_5wBX1NQZOEH-LK6", "source_drug_name": "GS002", "title": "GS002, a novel anti-PD-L1 ADC with targeted cytotoxic delivery and immune checkpoint inhibition", "abstract_text": "GS002 (also designated 002mAb-GSLP003) is an investigational anti-PD-L1 antibody-drug conjugate (ADC) with a drug-to-antibody ratio (DAR) of 8. It comprises a high-affinity, Fc-silent IgG1κ antibody engineered to promote endocytosis, site-specifically conjugated via a solubility-enhanced linker to a novel topoisomerase I inhibitor payload. A key distinguishing feature of GS002 is its optimized linker-payload system, which enhances solubility and stability, and incorporates a payload that is superior to DXd, exhibiting potent bystander killing while resisting drug efflux. Preclinically, GS002 demonstrates a dual mechanism of action, combining potent PD-L1-targeted cytotoxicity with immune checkpoint blockade. In vitro, GS002 mediated enhanced endocytosis relative to two competitor ADCs and induced potent cytotoxicity in PD-L1-positive tumor cells, with minimal impact on antigen-presenting cells such as M0 macrophages and myeloid dendritic cells. In vivo, GS002 elicited sustained antitumor activity across multiple cell-derived xenograft models, including EMC-1, KARPAS-299, and H1975, matching or exceeding the efficacy of 002mAb-GGFG-DXd and two competitor ADCs. The solubility-enhanced linker-payload design of GS002 conferred favorable pharmacokinetics in rats following a single 6 mg/kg IV dose, exhibiting closely overlapping plasma concentration-time curves for total and conjugated antibody. GS002 also demonstrated high plasma stability across species, with minimal premature payload release after 21 days at 37°C. Furthermore, its developability profile was comparable to the unconjugated antibody (002mAb), showing similar hydrophobicity and thermostability as evidenced by identical HIC retention times and closely matched Tm and Tagg values. In summary, GS002 represents a highly differentiated PD-L1-targeting ADC candidate with synergistic dual mechanisms, compelling efficacy in vitro and in vivo, a favorable pharmacokinetic profile, and excellent developability properties, supporting its advancement into further IND-enabling development.", "source_company": "Shanghai Ginspire Biologics Co., Ltd", "source_org_type": "公司", "row_number": 1281, "target_meta": "PDL1", "MOA_meta": "抗体偶联药物"}, {"drug_name": "XYD-8006", "company": "FDC Biotech", "org_type": "公司", "target": "ADAM9", "modality": "ADC", "importance_level": "中", "total_score": 64, "institution_score": 45, "track_score": 85, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 5, "brief_reason": "XYD-8006为靶向ADAM9的双payload ADC，旨在克服肿瘤异质性和单一payload耐药，展示优于单payload ADC的体外/体内疗效，并在GI和肺癌模型中实现肿瘤消退。机构为国内中小biotech（非头部），赛道ADC+双payload+新兴靶点ADAM9热度较高，preclinical强度强且计划2026年入临床。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4434", "id": "uJ7M_5wBZznHJdnt_W3O", "source_drug_name": "XYD-8006", "title": "XYD-8006: A novel ADAM9-targeting dual-payload ADC demonstrates superior preclinical efficacy in gastrointestinal and lung cancer models", "abstract_text": "Background: A Disintegrin And Metalloproteinase 9 (ADAM9) is a cell surface protease implicated in growth factor shedding, integrin binding, and cell migration, processes critical for tumor progression, metastasis, and neovascularization. Its overexpression is correlated with poor prognosis in multiple solid tumors, and overexpressed in GI and lung cancers but limited in normal tissues, highlighting its potential as a therapeutic target. While Antibody-Drug Conjugates (ADCs) represent a transformative oncology modality, single-payload ADCs face limitations including, tumor heterogenecity, the emergence of payload resistance such as DXD/SN38. To address this, we developed XYD-8006, a ADAM9-targeting ADC equipped with dual-payload platform designed to enhance efficacy and overcome tumor heterogenecity and DXD/SN38 resistance.\nMethods: XYD-8006, a humanized anti-ADAM9 IgG1 monoclonal antibody conjugated with high hydrophilic linker to two distinct potent payloads: a microtubule inhibitor and a topoisomerase I inhibitor, with a controlled and specific Drug-to-Antibody Ratio (DAR). The molecule was evaluated for specificity, internalization efficiency, and in vitro/in vivo efficacy across a panel of ADAM9-high, -medium, and -low expressing tumor models.\nResults: XYD-8006 exhibited high specificity for ADAM9 with no observed cross-reactivity to paralog family members and demonstrated superior internalization efficiency. In vitro and in vivo study showed, XYD-8006 induced potent, synergistic tumor cell killing, significantly outperforming single-payload ADC controls. Notably, it achieved robust tumor growth inhibition and regression not only in ADAM9-high models but also in models with medium and low ADAM9 expression. XYD-8006 exhibited potent ADAM9-targeted cytotoxicity and tumor suppression, with a favorable pharmacokinetic and safety profile.\nConclusion: XYD-8006 was designed to overcome key limitations of current ADC therapies. Its promising preclinical efficacy across gastrointestinal and lung cancers supports its further development, with an expected entry into clinical study in 2026.", "source_company": "FDC Biotech", "source_org_type": "公司", "row_number": 125, "target_meta": "ADAM9", "MOA_meta": "抗体偶联药物"}, {"drug_name": "B7-H3 CAR-DCs", "company": "Washington University School of Medicine in St. Louis", "org_type": "大学", "target": "B7-H3", "modality": "CAR", "importance_level": "中", "total_score": 64, "institution_score": 40, "track_score": 85, "milestone_score": 75, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "该产品为针对B7-H3的CAR工程化树突细胞（CAR-DCs），利用mRNA非整合递送实现首创平台，结合CAR精准性和DC交叉呈递能力，在实体瘤模型中诱导广谱持久抗肿瘤免疫。机构为大学非商业化，赛道为新型细胞治疗+热门靶点B7-H3，preclinical数据强劲且显示可扩展制造和IND准备价值。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10440", "id": "YVXM_5wBX1NQZOEH-LS6", "source_drug_name": "B7-H3 CAR-DCs", "title": "A novel, first in class chimeric antigen receptor dendritic cell platform driving broad and durable antitumor immunity in solid tumors", "abstract_text": "Chimeric Antigen Receptor Dendritic Cells (CAR-DCs) represent a new class of immunotherapy designed to overcome the key limitations of CAR-T and immune checkpoint blockade (ICB) in solid tumors. By engineering conventional dendritic cells (cDCs) with a tumor-targeting CAR delivered via non-integrating mRNA, we have harnessed the intrinsic ability of DCs to cross-prime a broad repertoire of antitumor CD8+ T cells. This approach merges the precision of CAR technology with the natural antigen-presenting potency of DCs, enabling broad immune activation by inducing polyclonal CD8⁺ T-cell responses that extend beyond CAR-restricted epitopes. To enable clinical advancement, we have developed a scalable human manufacturing process that reliably produces >300 million CAR-DCs, overcoming a longstanding barrier to the translational deployment of DC-based therapies. Immunotherapies such as CAR-T and ICB have transformed hematologic cancer treatment but remain ineffective in many solid tumors due to finite target antigens and dependance on pre-existing tumor-reactive T cells. To overcome these challenges, we engineered type I conventional DCs with a CAR recognizing B7-H3, a clinically relevant solid and liquid tumor antigen. In vitro, B7-H3 CAR-DCs displayed enhanced uptake of diverse tumor antigens, maturation, and superior cross-presentation of tumor derived antigens to CD8⁺ T cells, driving potent cytotoxic T-cell activation. In vivo, using a C57BL/6 syngeneic 1956 sarcoma model comprised of 75% B7-H3⁺ and 25% B7-H3⁻ tumor cells, untreated mice exhibited progressive disease. In contrast, both intratumoral and intravenous administration of B7-H3 CAR-DCs induced complete to almost complete tumor regression and confer durable protection upon rechallenge, demonstrating the establishment of robust, target-independent immunity. Analysis of tumor-draining lymph nodes (tdLNs) revealed that B7-H3 CAR-DCs delivered substantially greater amounts of tumor antigen to tdLNs. Correspondingly, transcriptional profiling of tdLN CD8⁺ T cells revealed signatures of enhanced activation, increased proliferative potential, and a shift toward memory formation which are hallmarks of efficient cross-priming. Mass spectrometry of MHC-I-cross presented peptides and tetramer analyses demonstrated CAR-DCs generated a broad expansion of endogenous tumor neoantigen-specific CD8⁺ T cells, confirming strong and effective diversification of the antitumor T-cell response. Together, these results position mRNA-engineered CAR-DCs as a first-in-class, translationally ready cell therapy platform that integrates antigen specificity, broadening of the antitumor T-cell response, durable memory formation, and GMP-compatible large-scale manufacturing thereby supporting rapid advancement toward IND-enabling studies and clinical evaluation in solid tumors.", "source_company": "Washington University School of Medicine in St. Louis", "source_org_type": "大学", "row_number": 897, "target_meta": "CD276", "MOA_meta": "其他"}, {"drug_name": "CLDN18.2 CAR-iNKT cells", "company": "Arovella Therapeutics", "org_type": "公司", "target": "CLDN18.2", "modality": "CAR", "importance_level": "中", "total_score": 64, "institution_score": 45, "track_score": 90, "milestone_score": 60, "field_heat_score": 85, "bonus_score": 3, "brief_reason": "靶点为CLDN18.2的CAR-iNKT细胞疗法，采用iNKT平台并加入IL-12-TM增强持久性，在体外对胃癌和胰腺癌细胞系显示强效持续杀伤。Arovella为小型澳洲上市biotech，机构分一般，但CLDN18.2热门+细胞治疗+固瘤赛道热度高，preclinical强度较好但尚未进入临床。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3689", "id": "fp7ECZ0BZznHJdntvNYd", "source_drug_name": "CLDN18.2 CAR-iNKT cells", "title": "Allogeneic CAR-iNKT cell therapy targeting CLDN18.2-positive gastric and pancreatic cancers", "abstract_text": "Allogeneic cell therapy offers the advantage of immediate and scalable access to healthy and potent effector cells for the treatment of solid tumors, overcoming patient immune dysfunction and potential manufacturing delays, while enabling durable anti-tumor responses. Invariant natural killer T (iNKT) cells are a rare, specialized subset of unconventional T cells that represent an ideal allogeneic cell therapy platform. They express a semi-invariant T cell receptor (iTCR) that recognizes glycolipid antigens presented by the monomorphic, MHC-like molecule, CD1d. Previous studies have shown that iNKT cells do not induce acute graft-versus-host disease, and iNKT cells engineered to express chimeric antigen receptors (CARs) have demonstrated therapeutic potential. In addition to tumor recognition via the CAR, iNKT cells can engage tumors via the endogenous iTCR binding to glycolipid-bound CD1d and via the NKG2D receptor. CAR-iNKT cells offer distinct advantages in the treatment of solid tumors due to their natural ability to home to tissues, infiltrate tumors, and modulate the tumor microenvironment.\nClaudin 18.2 (CLDN18.2) has emerged as a high-priority target for novel cancer therapies. Under normal physiological conditions, its expression is limited to tight junctions between epithelial cells and remains inaccessible on the cell surface. However, in several malignancies, including gastric, esophageal, and pancreatic cancers, CLDN18.2 becomes surface-exposed as tumor cells lose normal tissue architecture during growth and invasion. This aberrant presentation in malignant tissue makes CLDN18.2 an attractive target for CAR-directed cell therapies.\nHere, we present the first PBMC-derived CAR-iNKT cell therapy product targeting CLDN18.2. This second-generation CAR features a short chain variable fragment (scFv) derived from SPX-101, a novel monoclonal antibody engineered for enhanced affinity and selectivity for CLDN18.2. To support iNKT cell function, membrane-bound IL-12 (IL-12-TM) was incorporated to provide cytokine armouring, which has been shown to enhance CAR-iNKT cell activity. In this work, iNKT cells were isolated from healthy donor PBMCs, activated, transduced to express the CLDN18.2 CAR with and without IL-12-TM co-expression, and expanded in culture. Cytotoxic activity and effector expansion were evaluated using a serial tumor re-challenge assay against CLDN18.2-positive gastric and pancreatic cancer cell lines. CLDN18.2 CAR-iNKT cells exhibited potent and sustained cytotoxic activity against CLDN18.2-positive tumor cells, and co-expression of IL-12-TM improved the persistence and durability of response under repeated high tumour burden. These findings support the potential of cytokine-armoured CLDN18.2-directed CAR-iNKT cells as an allogeneic cell therapy for the treatment of gastric and pancreatic cancers.", "source_company": "Arovella Therapeutics", "source_org_type": "公司", "row_number": 991, "target_meta": "CLDN18.2", "MOA_meta": "其他"}, {"drug_name": "LV-169", "company": "Imanis Life Sciences", "org_type": "公司", "target": "BCMA", "modality": "other", "importance_level": "中", "total_score": 64, "institution_score": 45, "track_score": 85, "milestone_score": 75, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "LV-169为CD3靶向慢病毒载体递送anti-BCMA CAR，实现体内直接生成BCMA-CAR T细胞，针对多发性骨髓瘤模型显示单剂完全清除肿瘤且无明显毒性。机构为中小型biotech专注病毒载体和基因治疗，赛道为热门的in vivo CAR-T生成平台，preclinical数据强劲但尚未进入临床。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4576", "id": "FFXM_5wBX1NQZOEH-LO6", "source_drug_name": "LV-169", "title": "T-cell specific transcriptional control eliminates CAR-mediated off-target transduction by CD3-retargeted lentiviral vectors, enabling safe in vivo generation of potent αBCMA-CAR T cells", "abstract_text": "CAR T-cell therapy is a transformative treatment for hematologic malignancies. A key milestone to expand access to this technology is to enable CAR-T generation directly within the patient. For in vivo therapy, the CAR delivery vehicle must resist serum neutralization, target T cells and exhibit minimal or no off-target effects. We recently developed the CD3-targeted lentiviral vector LV-169 which delivers a BCMA CAR transgene to lymph node-resident primary T cells in vivo. LV169 incorporates a VSV-G protein that has been detargeted (blinded) from its natural LDL receptor and re-targeted to T cells via a displayed CD3-specific scFv. However, CAR proteins incorporated into the LV-169 envelope during packaging can induce off-target transduction of malignant plasma cells. Here, we reversed the orientation of the CAR transgene and placed it downstream of the human distal Lck promoter. In contrast to the EF1α promoter, the Lck promoter was transcriptionally silenced in 293 suspension cells but was insufficiently active in Jurkat cells and primary T cells. We therefore inserted a TATA box and a CMV enhancer into the Lck promoter (Lck1.3). The reverse-orientation Lck1.3-driven CAR construct (R-Lck1.3) did not express the BCMA-CAR protein in transfected 293 LV producer cells but was highly active in LV-transduced Jurkat cells and primary human T cells. Western blotting confirmed the high abundance of CAR protein in EF1a-driven vector particles and its absence in R-Lck1.3 particles. Therapeutic efficacy of LV169-R-Lck1.3 vectors encoding the BCMA-CAR was evaluated in human PBMC-engrafted NSG-DKO mice with advanced, disseminated human multiple myeloma. Mice were engrafted with OPM-2-FLuc cells and humanized with PBMCs one week prior to vector infusion. Tumor burden was monitored weekly via luciferase imaging. A single intravenous dose of LV169 (1×109 LVP) resulted in complete tumor clearance within 14 days. Circulating anti-BCMA CAR-T cells were detectable 14 days after LV injection but became undetectable once the tumor was eliminated. No severe toxicity was observed, based on stable body weight and cytokine levels in the blood. No tumor growth was observed in treated mice that were re-challenged with OPM-2 on days 22 and 30. In summary, our newly developed LV169-R-Lck1.3 platform encoding the BCMA-CAR demonstrates potent therapeutic activity, and its further clinical translation is underway.", "source_company": "Imanis Life Sciences", "source_org_type": "公司", "row_number": 1267, "target_meta": "BCMA", "MOA_meta": "其他"}, {"drug_name": "C018", "company": "Convalife Pharmaceuticals", "org_type": "公司", "target": "CDK4 & CDK9", "modality": "inhibitor", "importance_level": "中", "total_score": 63.5, "institution_score": 65, "track_score": 75, "milestone_score": 45, "field_heat_score": 70, "bonus_score": 2, "brief_reason": "C018为CDK4&9双靶点抑制剂，针对palbociclib耐药的ER+乳腺癌具有潜在协同克服耐药作用。Convalife为国内临床阶段创新药企，非头部但有一定管线布局；赛道为CDK抑制剂在耐药克服方向有热度但非最热门，尚处早期体外研究阶段，整体中等关注价值。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6419", "id": "sVXM_5wBX1NQZOEH-LG6", "source_drug_name": "C018", "title": "C018, a potent and selective CDK4&9 dual inhibitor", "abstract_text": "Background: CDK4&6 inhibitors have been approved for the treatment of metastatic ER+&HER2- breast cancer, either as monotherapy or in combination with endocrine therapy. However, many patients develop resistance to CDK4&6 inhibition through multiple mechanisms, including loss of the tumor suppressor Rb, hyperactivation of CDK4&6, and&or upregulation of CDK2&Cyclin E1 expression and activity, resulting in a significant unmet clinical need. CDK9 plays a critical role in RNA transcription as a catalytic subunit of positive transcription elongation factor b (P-TEFb), which phosphorylates the negative elongation factor (NELF), DRB sensitivity-inducing factor (DSIF), and the Ser2 residue within the C-terminal domain (CTD) of RNA polymerase II (Pol II), ultimately triggering transcriptional elongation. Accumulating evidence suggests that CDK9 activity may contribute to palbociclib resistance mechanisms, and targeting CDK9 represents a promising strategy to overcome resistance in breast cancer.\nMethods and Materials:Based on structure-activity relationship (SAR) studies and accelerated by the Convalife \"AIDRUG.WORK\" molecular design platform, we completed the early-stage screening of CDK4&9 inhibitors. The lead compound demonstrated >30-fold selectivity for CDK4 over CDK6 and >80-fold selectivity for CDK9 over CDK6. To explore the therapeutic potential of CDK4&9 dual inhibitors against palbociclib-resistant tumors, we evaluated the effects of CDK4&9 inhibition on cell viability using both palbociclib-sensitive and palbociclib-resistant MCF-7 cell lines.\nResults:The CDK4&9 inhibitor significantly impaired the viability of both palbociclib-sensitive and palbociclib-resistant MCF-7 cell lines through concurrent inhibition of CDK4 and CDK9 activity.\nConclusions:Our findings demonstrate that simultaneous inhibition of CDK4 and CDK9 may exert synergistic effects in overcoming palbociclib resistance. CDK4&9 dual inhibition represents a promising therapeutic strategy to overcome both endocrine therapy and CDK4&6 inhibitor resistance in ER+ breast cancer, warranting further clinical development as a novel approach for treating resistant breast cancer.", "source_company": "Convalife Pharmaceuticals", "source_org_type": "公司", "row_number": 192, "target_meta": "CDK4,CDK9", "MOA_meta": "抑制剂"}, {"drug_name": "MGT-1142", "company": "Marigold Therapeutics, Inc.", "org_type": "公司", "target": "novel glycan", "modality": "ADC", "importance_level": "中", "total_score": 63.5, "institution_score": 45, "track_score": 85, "milestone_score": 70, "field_heat_score": 75, "bonus_score": 3, "brief_reason": "MGT-1142为靶向肿瘤特异性新型糖链的exatecan-based ADC，在SCLC中展示强效选择性抗肿瘤活性及良好药代/耐受性。机构为2024年底新成立的ADC专注新兴biotech（非头部），但ADC+新型糖靶点赛道热度高，前临床数据扎实，综合潜力中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4039", "id": "5VXM_5wBX1NQZOEH-LK6", "source_drug_name": "MGT-1142", "title": "MGT-1142, an antibody-drug conjugate targeting a novel glycan for small-cell lung cancer", "abstract_text": "Background: Aberrant glycosylation is a hallmark of many malignancies, driving tumor growth, immune evasion, and metastasis. Certain tumor-associated glycans are highly expressed in small-cell lung cancer (SCLC) but minimally present in normal tissues, making them attractive yet underexplored targets for antibody-drug conjugates (ADCs). MGT-1142 is an exatecan-based ADC engineered with an optimized Fc domain to recognize a tumor-specific glycosylation pattern and selectively deliver a potent topoisomerase I inhibitor payload.\nMethods: Comprehensive in vitro and in vivo evaluations were performed to characterize MGT-1142. Binding affinity, internalization, and cytotoxicity were examined across multiple SCLC cell lines. Anti-tumor efficacy was assessed in both cell line-derived xenograft (CDX) and patient-derived xenograft (PDX) models. Pharmacokinetic (PK) and dose-range-finding (DRF) studies were conducted in cynomolgus monkeys to determine systemic exposure, half-life, and tolerability.\nResults: MGT-1142 exhibited high target specificity with no detectable cross-reactivity to structurally related glycans. It demonstrated strong binding and rapid internalization in glycan-positive cells, resulting in potent inhibition of antigen-positive tumor cell proliferation. In vivo, MGT-1142 achieved dose-dependent tumor growth inhibition across multiple CDX and PDX models. Cynomolgus PK studies revealed linear, dose-proportional exposure and a favorable terminal half-life. Dose range finding studies indicated good tolerability and a wide therapeutic window.\nConclusions: MGT-1142 shows potent and selective anti-tumor activity, favorable pharmacokinetics, and an encouraging safety profile in preclinical studies. These findings support MGT-1142 as a potential first-in-class glycan-targeting ADC for the treatment of small-cell lung cancer.", "source_company": "Marigold Therapeutics, Inc.", "source_org_type": "公司", "row_number": 224, "target_meta": "not available", "MOA_meta": "抗体偶联药物"}, {"drug_name": "hYP7-hYP7 γδAbTCR-T cells", "company": "National Cancer Institute", "org_type": "研究机构", "target": "GPC3", "modality": "CAR", "importance_level": "中", "total_score": 63.5, "institution_score": 45, "track_score": 85, "milestone_score": 65, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "靶向GPC3的γδAbTCR-T细胞疗法，采用hYP7双同源设计增强低/异质抗原密度下的识别和杀伤能力。NCI机构得分有限，但γδT改造+肝癌异质性克服机制在热门细胞治疗赛道中具潜力，in vivo优效数据支持中度重要性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5231", "id": "wVXM_5wBX1NQZOEH-LO6", "source_drug_name": "hYP7-hYP7 γδAbTCR-T cells", "title": "The GPC3-targeting hYP7 antibody-based gamma/delta TCR-T cell therapy for overcoming antigen mutation and heterogeneity in liver cancer", "abstract_text": "Antigen mutation and heterogeneous expression remain major barriers to effective antibody- and chimeric antigen receptor (CAR)-based immunotherapies for hepatocellular carcinoma (HCC). Glypican-3 (GPC3) exhibits variable surface density and epitope alteration in advanced or recurrent HCC tumors. To address these clinically relevant obstacles, we developed a modular antibody-based γ/δ T-cell receptor (γδAbTCR) platform that integrates antibody specificity with intrinsic TCR-CD3 signaling to enhance tumor recognition under conditions of antigen variation. Using two GPC3 antibodies recognizing distinct epitopes (hYP7 and HN3), we generated four γδAbTCR constructs—hYP7-hYP7, hYP7-HN3, HN3-hYP7, and HN3-HN3—and evaluated their functional properties in primary human T cells. Among these, hYP7-hYP7 γδAbTCR-T cells demonstrated the strongest antigen binding and cytotoxic activity against Hep3B and other GPC3⁺ HCC models, particularly those with low or heterogeneous antigen density. In vivo, hYP7-hYP7 T cells showed superior tumor infiltration, persistence, and control of large, established xenografts compared with other configurations. Mechanistic studies revealed that the hYP7-hYP7 γδAbTCR architecture couples enhanced antigen-binding avidity with coordinated TCR-CD3 and CD30 signaling, leading to potent NF-κB and NFAT activation and rapid induction of caspase-mediated apoptosis in tumor cells. These findings establish hYP7-hYP7 as a lead γδAbTCR design that overcomes the limitations of antigen heterogeneity and mutation in liver cancer, providing a promising framework for next-generation T-cell therapies targeting liver cancer.", "source_company": "National Cancer Institute", "source_org_type": "研究机构", "row_number": 246, "target_meta": "GPC3", "MOA_meta": "其他"}, {"drug_name": "humanized CT3 AbTCR T cells", "company": "NIH/NCI", "org_type": "政府机构", "target": "GPC2", "modality": "CAR", "importance_level": "中", "total_score": 63.5, "institution_score": 45, "track_score": 85, "milestone_score": 65, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "靶向GPC2的humanized AbTCR T细胞（抗体-TCR融合新型细胞疗法），利用生理TCR信号改善实体瘤尤其是低抗原表达神经母细胞瘤的持久杀伤力。NIH/NCI机构得分一般但赛道热门（新型细胞治疗+实体瘤突破）、机制亮点和强效preclinical数据支撑中上重要性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5227", "id": "t1XM_5wBX1NQZOEH-LG6", "source_drug_name": "humanized CT3 AbTCR T cells", "title": "Humanized antibody Fab-TCR T cells targeting GPC2 effectively regress neuroblastoma via enhanced TCR signaling and sustained cytotoxicity", "abstract_text": "Background and Significance: Chimeric antigen receptor (CAR) T cell therapy has revolutionized the treatment of hematologic cancers but remains less effective against solid tumors, where heterogeneous antigen expression poses a major barrier to efficacy. Neuroblastoma, a pediatric solid tumor with poor survival rates in high-risk patients, often expresses glypican-2 (GPC2), a promising yet variably expressed surface antigen. To overcome these challenges, we engineered antibody-T cell receptors (AbTCRs) that combine antibody-based antigen recognition with the signaling machinery of γ/δ T cell receptors, aiming to promote more physiological activation and sustained antitumor activity in GPC2-positive neuroblastoma.\nMethods: We developed AbTCRs containing anti-GPC2 Fab fragments (humanized CT3 or murine CT3) fused to γ/δ TCR constant regions and a co-stimulatory domain, CD30. Primary human T cells were transduced with these constructs and tested through in vitro tumor-killing assays, repeated cytotoxicity tests, western blotting, and in vivo xenograft models bearing GPC2 neuroblastoma (IMR5, NBEB, LAN1, and SH-SY5Y) tumors. The LAN1 and SH-SY5Y models have low GPC2 antigen density, enabling evaluation of efficacy under stringent antigen conditions.\nResults: We found strong anti-tumor effects in humanized CT3 AbTCR-T cells, including significant tumor reduction and complete responses in multiple xenograft models. Tumors from mice administered with humanized CT3 AbTCR-T cells showed notably augmented infiltration of CD8⁺ and CD8⁺CD27⁺ T cells, consistent with enhanced effector persistence. Humanized CT3 AbTCR-T cells demonstrated downregulation of exhaustion markers PD1, LAG3, and TIM3 and an enriched less-differentiated Tscm subset, as assessed by peripheral blood testing. These cells maintained lower PD1 levels after prolonged coculture with tumor cells, and retained cytotoxic activity in second- and third-round killing assays. Mechanistically, upon tumor engagement, hCT3 AbTCRs elicited more robust TCR signaling, evidenced by higher NFAT nuclear translocation and greater phosphorylation of key TCR pathway proteins.\nConclusion: Humanized CT3 AbTCR T cells exhibit durable and potent antitumor effects against low-GPC2 neuroblastoma by combining antibody specificity with physiological TCR signaling. Their enhanced TCR signaling, reduced exhaustion, and sustained cytotoxic ability suggest that AbTCR T cells represent a promising next-generation cellular therapy for solid tumors with heterogeneous or low antigen expression.", "source_company": "NIH/NCI", "source_org_type": "政府机构", "row_number": 442, "target_meta": "GPC2", "MOA_meta": "其他"}, {"drug_name": "PD-L1-ATRi ADC", "company": "DCx Biotherapeutics", "org_type": "公司", "target": "PD-L1", "modality": "ADC", "importance_level": "中", "total_score": 63.5, "institution_score": 45, "track_score": 85, "milestone_score": 65, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "该ADC以PD-L1为靶点递送新型ATR抑制剂payload，针对DNA修复缺陷肿瘤实现精准递送以提升疗效窗口。机构为2025年新成立的preclinical阶段加拿大biotech公司，非头部MNC或知名biotech导致机构分较低，但ADC+ATRi创新机制结合热门靶点和赛道使其赛道分和领域热度较高，preclinical数据显示良好体内外选择性和疗效。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5118", "id": "vlXM_5wBX1NQZOEH-LG6", "source_drug_name": "PD-L1-ATRi ADC", "title": "Novel ATR inhibitor payloads for antibody-drug conjugates targeting PD-L1", "abstract_text": "Ataxia telangiectasia and Rad3-related kinase (ATR) is essential to the faithful replication of DNA in rapidly dividing cells such as cancer cell lines. ATR is activated in response to single-strand DNA breaks that result from increased replication stress caused by defects in DNA repair mechanisms and/or damaged DNA. ATR stabilizes and restarts the stressed replication forks, suppresses origin firing, activates cell cycle checkpoints, and facilitates DNA repair. In fact, ATR activity contributes to the tolerance of chronic replication stress in cells transformed by oncogenes rendering cancer cells more dependent on ATR activity for survival. Systemic exposure to ATR inhibitors (ATRis) in clinical studies have demonstrated dose-limiting toxicities that reduce their clinical utility. Therefore, precision antibody-drug conjugates (ADCs) for targeted delivery of ATR payloads could bypass the systemic toxicities associated with oral administration. There is significant overlap between cancers with ATRi sensitizing defects in DNA repair mechanisms with those expressing high levels of PD-L1 surface antigens including stomach, breast, lung and colon cancers. Our personalized antibody-drug conjugate approach couples surface targeted therapeutics to tumors with increased sensitivity to the delivered payload to improve the therapeutic index. We have discovered multiple derivatizable proprietary ATRis with desirable physicochemical properties that demonstrate low nM potency in cancer cell lines with ATRi sensitizing mutations. Furthermore, the ATRi payloads maintained in vitro cytotoxic potency in cells harbouring clinically relevant acquired resistance mutations in Topoisomerase 1, whereas exatecan did not. Once conjugated to the anti-PD-L1 monoclonal antibody, the resulting ADCs demonstrated selective picomolar cellular growth inhibition and excellent metabolic stability in mouse plasma. Preclinical in vivo studies in mice demonstrate robust efficacy and selectivity with PD-L1-ATRi as single agent relative to IgG-ATRi. The in vitro and in vivo data presented herein demonstrate the efficacy of an ADC with an ATRi mono-payload and illustrate the potential for combinations with standard of care chemotherapeutic agents such as gemcitabine or PARP inhibitors.", "source_company": "DCx Biotherapeutics", "source_org_type": "公司", "row_number": 444, "target_meta": "PDL1", "MOA_meta": "抗体偶联药物"}, {"drug_name": "G12Ci", "company": "Massachusetts General Hospital", "org_type": "医院", "target": "KRAS G12C", "modality": "inhibitor", "importance_level": "中", "total_score": 63.5, "institution_score": 40, "track_score": 95, "milestone_score": 60, "field_heat_score": 85, "bonus_score": 3, "brief_reason": "G12Ci为KRAS G12C抑制剂，靶向肺癌最大突变亚群，赛道极热；研究机构为医院而非药企，preclinical机制研究显示YAP-TEAD联合潜力，但无明确临床里程碑。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5067", "id": "wFXM_5wBX1NQZOEH-LG6", "source_drug_name": "G12Ci", "title": "Characterizing drug-induced transcriptional reprogramming in KRAS mutant lung cancer", "abstract_text": "KRAS mutations define the largest genomic subset of non-small cell lung cancer (NSCLC). Recently, inhibitors that selectively target the KRASG12C mutation (G12Ci) have been developed, however, clinical responses are incomplete and short-lived due to intrinsic and adaptive drug resistance. Combination drug strategies designed to inhibit adaptive resistance by targeting reactivation of the MAPK pathway have demonstrated limited efficacy and significant dose-limiting toxicity. Therefore, new strategies to overcome drug resistance are needed. In some contexts, resistance to oncogene-directed therapies in NSCLC can be linked to dysregulation of the Hippo pathway, a key cell growth control pathway that is conserved across species. Recent preclinical studies have suggested that dysregulation of the Hippo pathway and activation of YAP and its corresponding transcription factor TEAD promote adaptive resistance in KRAS-mutant lung cancer models, which can be overcome by combining YAP-TEAD inhibitors with G12Ci. However, our mechanistic understanding of how YAP drives adaptive resistance is incomplete. Using patient-derived KRASG12C-mutant models, we show that G12Ci induces progressive YAP-dependent and YAP-independent transcriptional reprogramming. We identify lineage programs regulated by YAP during adaptation to G12Ci that are derepressed upon co-treatment with a YAP-TEAD inhibitor. These results reveal insights into non-genomic adaptive drug resistance in lung cancer and will enable future development of rational drug combination strategies to overcome therapeutic resistance.", "source_company": "Massachusetts General Hospital", "source_org_type": "医院", "row_number": 446, "target_meta": "KRAS G12C", "MOA_meta": "抑制剂"}, {"drug_name": "CAR-NKstem", "company": "UT MD Anderson Cancer Center", "org_type": "医院", "target": "未披露", "modality": "CAR", "importance_level": "中", "total_score": 63.5, "institution_score": 45, "track_score": 85, "milestone_score": 70, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "该产品为通过代谢重编程（线粒体重塑）增强干性及持久性的CAR-NK细胞，靶点未披露，但聚焦CAR-NK细胞在实体瘤中的代谢优化和新制造策略。机构为顶级肿瘤医院而非商业公司得分为中等，赛道为热门细胞治疗+代谢工程且有体外/体内优效数据，综合潜力较高故总分中偏上。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9413", "id": "HVXM_5wBX1NQZOEH-LK6", "source_drug_name": "CAR-NKstem", "title": "Mitochondrial remodeling sustains CAR-NK stemness for superior tumor control", "abstract_text": "Background: NK cell-based therapies are a promising off-the-shelf strategy for cancer treatment. Their inherent safety and lack of graft-versus-host disease make NK cells an attractive platform for CAR engineering, combining innate cytotoxicity with receptor specificity. However, clinical efficacy in solid tumors is limited by poor persistence and rapid metabolic exhaustion in the tumor microenvironment (TME). Strategies that enhance metabolic fitness and delay differentiation are essential. Inspired by stem-cell culture systems, we tested whether Albumin Polyvinylalcohol Essential Lipids (APEL), a defined medium used to support iPSC differentiation into embryoid bodies and NK cells, could preserve CAR-NK stemness and improve metabolic fitness and function.\nMethods: CAR-NK cells expanded with APEL (CAR-NKstem) were compared with CAR-NK cells expanded in conventional NK cell media (CAR-NKconv). Metabolic profiling included mitochondrial mass and potential profiling, Seahorse assays to measure glycolysis and oxidative phosphorylation, nutrient competition assays to assess metabolic flexibility. CAR-NK cells were cultured with various hematologic and solid tumor cell lines, followed by cytotoxicity evaluation using 2D xCelligence and 3D Incucyte including rechallenge assays to assess serial killing capacity. In vivo efficacy was tested using various xenograft mouse models of hematologic cancers (MOLM14, MM1s) and solid tumors (786-0 ongoing). Mechanistic studies included multiomics profiling by bulk RNA-seq and ATAC-seq, CyTOF, and mitochondrial-transfer assays.\nResults: Our data show that early metabolic reprogramming of CAR-NKstem during expansion drove the development of enlarged and highly active mitochondria, increased spare respiratory capacity (SRC), and superior metabolic flexibility. This metabolic state stabilized stem-like features and limited terminal differentiation via chromatin remodeling toward persistence and memory-associated programs. Functionally, CAR-NKstem cells showed improved proliferation, sustained serial killing, superior nutrient competition, and enhanced tumor control in vitro and in vivo. Mechanistically, mitochondrial transfer from CAR-NKstem cells enhanced cytotoxicity and persistence in recipient NK cells, highlighting mitochondrial remodeling as a key driver of functional fitness.\nConclusion: These findings demonstrate that targeted metabolic reprogramming during manufacturing can generate stem-like, highly persistent CAR-NK cells and offer a broadly applicable, immediately translatable strategy for cancer immunotherapy.", "source_company": "UT MD Anderson Cancer Center", "source_org_type": "医院", "row_number": 509, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "CRAFT CAR T-cells", "company": "Mayo Clinic", "org_type": "医院", "target": "CD19, BAFF-R", "modality": "CAR", "importance_level": "中", "total_score": 63.5, "institution_score": 45, "track_score": 85, "milestone_score": 65, "field_heat_score": 80, "bonus_score": 4, "brief_reason": "CRAFT CAR T-cells为新型CD3保留型同种异体CAR T平台，针对CD19和BAFF-R，采用AsCas12a Ultra+TRBC crRNA实现更安全编辑，显著降低脱靶和GVHD风险，并支持BiTE协同。Mayo Clinic虽为顶级学术医院，但非商业药企导致机构分较低，赛道热门+创新机制+体内持久性带来中偏高综合价值。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5226", "id": "Rp7ECZ0BZznHJdntvNYd", "source_drug_name": "CRAFT CAR T-cells", "title": "CD3-positive allogeneic CAR T-cells: A novel platform with persistence, BiTE-capture, and no alloreactivity", "abstract_text": "Several allogeneic CAR T-cell therapies are in clinical trials to evaluate safety, many of which rely on CRISPR/Cas-based genome editing. However, the Cas enzyme’s random repair mechanism elevates the risk of undesired, off-target effects, posing a challenge for safe allogeneic CAR T-cell generation. To mitigate the risk of therapy-related oncogenesis, we sought to pursue an alternative safe strategy to manufacture allogeneic CAR T-cells distinct from the preexisting ones in the clinic. We have developed a CRISPR RNA (crRNA) targeting T-cell receptor beta constant (TRBC) gene, which in conjunction with AsCas12a Ultra enzyme, causes site-specific editing by eliciting a predictable microhomology-mediated end joining (MMEJ) DNA repair pathway, which mitigates off-targeting risk. Targeted amplicon sequencing was employed to evaluate off-targeting and repair mechanisms. Graft versus host alloreactivity as well as CAR T persistence was evaluated using immunocompromised mice. In vivo tumor challenge study was conducted for over 3 months. Engraftment confirmation was done using immunohistochemistry and flow cytometry. Interestingly while evaluating the edited T-cells, we sequestered a unique T-cell population that showed TCR disruption yet remained CD3-positive and did not cause in vivo alloreactivity. These CD3-Retained, Allogeneically Functioning T-cells (CRAFT-cells) showed a similar growth rate as unedited T-cells and were then used as a platform to produce CD19-targeted CAR T-cells and BAFF-R-targeted CAR T-cells. When compared to the standard CD3-disrupted allogeneic CAR T-cells, CRAFT CAR T-cells displayed an equally robust cytotoxicity while possessing a safer genomic profile. CRAFT CAR T-cells could function as effector cells for bispecific T-cell engager (BiTE) and induce CD3-dependent cytotoxicity against tumor cells. Pertinently, CRAFT CAR T-cells as opposed to CD3-disrupted CAR T-cells, were present in mouse xenografts without alloreactivity. Having the onset of MMEJ-directed repair and minimal off-targeting, positions this CRAFT crRNA to generate safer allogeneic CAR T-cells with an overall reduced genotoxic profile in a clinical setting. This unique CRAFT CAR T-cell population displays in vivo persistence. Additionally, CRAFT CAR T can be combined with BiTE therapy, offering a promising and potentially more durable alternative to preexisting ex vivo allogeneic CAR T-cell therapies.", "source_company": "Mayo Clinic", "source_org_type": "医院", "row_number": 529, "target_meta": "CD19,TNFRSF13C", "MOA_meta": "其他"}, {"drug_name": "CADM1-GGFG-Exatecan ADC", "company": "UT MD Anderson Cancer Center", "org_type": "医院", "target": "CADM1", "modality": "ADC", "importance_level": "中", "total_score": 63.5, "institution_score": 45, "track_score": 85, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "靶向CADM1的ADC在骨肉瘤中显示出强靶点依赖的体外细胞毒性，CADM1表面表达与GGFG-Exatecan linker-payload ADC效力高度相关（ρ=-0.98），支持其作为骨肉瘤潜在治疗靶点。机构为顶级肿瘤医院但非药企导致institution_score中等，ADC+新型靶点在儿科实体瘤未满足需求下track_score和field_heat较高，处于优化候选药物preclinical阶段。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1808", "id": "pFXM_5wBX1NQZOEH-LK6", "source_drug_name": "CADM1-GGFG-Exatecan ADC", "title": "Surface CADM1 (Cell Adhesion Molecule 1) abundance predicts payload delivery and in-vitro efficacy of CADM1-GGFG-Exatecan ADC in osteosarcoma, aiding optimal candidate selection", "abstract_text": "Background: ADC development in osteosarcoma has been hindered by the absence of effective, targetable surface antigens. We previously identified CADM1, a cell-surface adhesion molecule, as a promising therapeutic target and generated three CADM1-directed ADCs (CADM1-Tesirine, CADM1-PEG-Exatecan, and CADM1-GGFG-Exatecan) with distinct linker-payload combinations. To select the optimal candidate for clinical translation, we evaluated target engagement and target-dependent cytotoxicity across multiple in vitro models.\nMethods: Confocal microscopy was used to visualize ADC trafficking through cellular compartments and its lysosomal localization over time. CADM1 knockout (KO) osteosarcoma cell lines (SaOS2 and OS31) were generated using CRISPR/Cas9 and validated by flow cytometry, Western blotting, and mass spectrometry (MS). Cell-surface CADM1 levels were quantified by MS and correlated with ADC cytotoxicity (IC₅₀ values) measured by real-time live-cell imaging on the IncuCyte platform. Spearman correlation analyses across nine osteosarcoma cell lines assessed the relationship between CADM1 expression and ADC potency for all three constructs.\nResults: Confocal time-course imaging showed ADC trafficking from the plasma membrane (30 min) to lysosomes (6 h) and cytoplasmic dispersion (24 h), absent in CADM1-KO cells, confirming target-mediated internalization and lysosomal processing. CRISPR/Cas9-mediated knockout of CADM1 was achieved in SaOS2 and OS31 osteosarcoma cell lines. Loss of CADM1 expression was confirmed by flow cytometry, Western blotting, and mass spectrometry, showing complete depletion of surface protein. CADM1 loss markedly reduced ADC cytotoxicity (IC₅₀ = 77.41 nM in SaOS2 CADM1-KO vs 0.014 nM in SaOS2), confirming on-target activity. Across nine osteosarcoma models, CADM1 surface abundance strongly correlated with drug potency, most notably for CADM1-GGFG-Exatecan (Spearman ρ = -0.98, p = 0.001). These data identify CADM1 as a determinant of ADC efficacy and highlight the contribution of other ADC components.\nConclusions: These data demonstrate potent, target-dependent activity of the generated CADM1-targeted ADCs, validating CADM1 as a rational therapeutic target. Among them, CADM1-GGFG-Exatecan showed the strongest correlation between IC₅₀ and target expression, supporting selective cytotoxic delivery. In vivo efficacy and toxicology studies are ongoing to finalize candidate selection.", "source_company": "UT MD Anderson Cancer Center\nThe University of Texas MD Anderson Cancer Center", "source_org_type": "医院", "row_number": 590, "target_meta": "CADM1", "MOA_meta": "抗体偶联药物"}, {"drug_name": "KRASG12V-targeted TCR-T cells", "company": "Mayo Clinic Arizona", "org_type": "医院", "target": "KRASG12V", "modality": "CAR", "importance_level": "中", "total_score": 63.5, "institution_score": 45, "track_score": 85, "milestone_score": 65, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "靶向KRASG12V突变的新抗原TCR-T细胞，采用噬菌体展示库快速分离高亲和力TCR，在体外和异种移植模型中显示出强效抗肿瘤活性。机构为知名医院而非头部药企得中等分，热门neoantigen+细胞治疗赛道高分，preclinical阶段有清晰体内外数据和安全性证据得较高里程碑分，综合热度较高但无临床数据。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5228", "id": "BVXM_5wBX1NQZOEH-LO6", "source_drug_name": "KRASG12V-targeted TCR-T cells", "title": "KRASG12V- and CTAG1B-targeted TCR-T cells from phage TCR library suppress colorectal and esophageal tumors", "abstract_text": "Background: Colorectal cancer (CRC) remains a leading cause of cancer-associated mortality and is difficult to treat due to therapy resistance and limited durable responses. Esophageal cancer (EC) is similarly challenging, exhibiting highly aggressive and metastatic behavior that contribute to its poor prognosis. Adoptive TCR-engineered T cell (TCR-T) therapies show promise in these settings, but their efficacy is limited by suboptimal antigen specificity and an immunosuppressive tumor microenvironment (TME). To address these barriers, we isolated high-affinity TCRs from a phage-displayed TCR library targeting KRASG12V neoantigen in CRC and CTAG1B cancer/testis antigen (CTA) in EC.\nMethods: KRASG12V(8-16)/HLA-A11:01-restricted and CTAG1B(157-165)/HLA-A02:01-restricted TCRs were isolated from an optimized phage-displayed TCR library generated from healthy donor CD8⁺ T cells through high-throughput biopanning. Binders were screened against antigen-family peptides and irrelevant controls by phage ELISA to eliminate cross-reactivity. Binding affinities were measured by SPR. Antigen-specific TCRs (asTCRs) were cloned into lentiviral vectors and transduced into primary human T cells. TCR-T function was assessed using peptide-pulsed T2 cells and KRASG12V⁺ or CTAG1B⁺ tumor cells through LDH-release cytotoxicity and cytokine secretion assays. Normal human cells were used to evaluate off-target toxicity. In vivo antitumor activity was tested in NOD/SCID-IL2rγ⁻/⁻ xenografts with histological confirmation of TCR-T infiltration.\nResults: Next-generation sequencing confirmed that the 109-scale library contained >90% functional genes and >80% sequence diversity. Three high-affinity TCRs were identified for each antigen (KD as low as 1.07 μM). These TCRs exhibited strict antigen specificity with no detectable cross-reactivity. TCR-T cells expressing asTCRs showed potent antigen-dependent cytotoxicity against KRASG12V⁺/HLA-A11:01⁺ colorectal and CTAG1B⁺/HLA-A02:01⁺ esophageal tumor cells (up to 80% lysis, p<0.01), accompanied by robust IFN-γ and TNF-α secretion (>1000 pg/mL, p<0.01). No killing was observed against any of seven healthy cell types. TCR-T cells remained effective at low effector-to-target ratios and maintained stable proliferation and effector-memory phenotypes. In xenograft models, KRAS- and CTAG1B-targeted TCR-T cells induced significant tumor regression compared to unmodified T cell controls (p<0.05), with increased effector TCR-T infiltration, and reduced antigen escape.\nConclusions: This work establishes a rapid and robust platform for isolating potent, safe, antigen-specific TCRs targeting both oncogenic driver mutation (KRASG12V) and an immunogenic CTA (CTAG1B). TCR-T cells demonstrated strong antitumor activity in vitro and in vivo, supporting the translational potential of this approach for solid tumor treatment.", "source_company": "Mayo Clinic Arizona", "source_org_type": "医院", "row_number": 657, "target_meta": "KRAS G12V", "MOA_meta": "其他"}, {"drug_name": "PRAME-specific TCR T cell therapy", "company": "Heidelberg University Hospital", "org_type": "医院", "target": "PRAME", "modality": "CAR", "importance_level": "中", "total_score": 63.5, "institution_score": 40, "track_score": 85, "milestone_score": 80, "field_heat_score": 75, "bonus_score": 5, "brief_reason": "靶点为癌症-睾丸抗原PRAME，modality为TCR工程化T细胞疗法（细胞治疗热门赛道），在重度预处理的多灶性肾母细胞瘤患儿中诱导深度缓解，体现临床转化潜力；机构为大学医院而非商业公司，得分较低，但point-of-care制造+重症儿科罕见瘤深缓解为亮点。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11362", "id": "KZ7M_5wBZznHJdnt_W3O", "source_drug_name": "PRAME-specific TCR T cell therapy", "title": "Point-of-care-manufactured PRAME-specific TCR T cell therapy induces deep remission in a heavily pre-treated pediatric patient with extensive, multifocal nephroblastoma", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Heidelberg University Hospital", "source_org_type": "医院", "row_number": 979, "target_meta": "PRAME", "MOA_meta": "其他"}, {"drug_name": "c-Myc RNA-targeting small molecules", "company": "Wayfinder Biosciences", "org_type": "公司", "target": "c-Myc mRNA", "modality": "small molecule", "importance_level": "中", "total_score": 63.5, "institution_score": 45, "track_score": 85, "milestone_score": 75, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "靶向c-Myc mRNA的RNA靶向小分子，通过抑制翻译实现c-Myc蛋白敲低，属于新兴热门赛道且c-Myc为经典undruggable靶点。Wayfinder为早期biotech，preclinical阶段已获口服生物利用度>60%并在SCLC CDX模型显示肿瘤抑制，潜力较高但机构仍处早期。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6696", "id": "EJ7M_5wBZznHJdnt_W7O", "source_drug_name": "c-Myc RNA-targeting small molecules", "title": "Potent, orally bioavailable small molecules that inhibit c-Myc translation and suppress tumor growth in vivo", "abstract_text": "Dysregulation of c-Myc is implicated in over half of all cancers, making it the most important undrugged oncogene. As a transcription factor, the c-Myc protein is not amenable to traditional small molecule inhibition. Recent attempts to reduce c-Myc activity with novel modalities have had limited success in the clinic, highlighting the need for Myc-targeted therapeutics with improved potency and cell permeability. We previously reported discovery of small molecules that bind to structured elements in the 5’ UTR of the c-Myc mRNA and repress translation of the c-Myc protein. Here, we describe our hit-to-lead campaign, in which we dramatically improved the potency (>70x), selectivity (>5x) and oral bioavailability (>13x) of our c-Myc RNA-targeting small molecules, yielding a lead series that suppresses tumor growth in an in vivo cell line-derived xenograft (CDX) model of small cell lung cancer (SCLC).\nUsing a ligand-based approach, we designed and synthesized over 150 analogs of our top hit series and characterized their ability to repress c-Myc protein levels and reduce viability of the highly MYC-amplified SCLC cell line NCI-H82. Notably, we observe excellent correlation between c-Myc protein repression and compound potency, supporting an on-target mechanism. Our compounds demonstrate rapid (~30 min half-life), selective and reversible protein knockdown, consistent with inhibition of c-Myc translation initiation followed by normal protein turnover. We have now achieved single-digit nanomolar potency and continue to make improvements thanks to the establishment of a strong structure-activity relationship for our lead series.\nIn parallel, we dramatically improved the ADME/PK properties of our series by identifying and correcting a structural liability for liver metabolism. The resulting tool molecule achieved >60% oral bioavailability and exposure above the in vitro IC50 for extended periods, enabling twice-daily oral dosing. This compound achieved significant tumor growth inhibition in a SCLC CDX model and, importantly, dosing was well tolerated by all animals. Beyond SCLC, we observe in vitro efficacy against cell lines from a range of solid and heme cancers, opening the door for xenograft studies in additional indications.\nTogether, our results validate an RNA-targeted small molecule approach to repress c-Myc. Our promising in vivo data, coupled with sustained oral exposure and favorable tolerability, highlight the potential of this modality to overcome long-standing barriers in MYC drug discovery. Ongoing xenograft and mechanistic studies are expected to further expand the clinical opportunities for treating MYC-driven solid and hematologic cancers.", "source_company": "Wayfinder Biosciences", "source_org_type": "公司", "row_number": 1139, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "a novel anti-hHER2 antibody-drug conjugate", "company": "Mimabs", "org_type": "公司", "target": "HER2", "modality": "ADC", "importance_level": "中", "total_score": 63.5, "institution_score": 45, "track_score": 90, "milestone_score": 60, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "新型anti-HER2 ADC，靶点HER2在乳腺癌等领域成熟且热门，modality为ADC赛道高热度；Mimabs为欧洲小型CRO公司，非头部药企，开发处于preclinical优化阶段，展示快速筛选和高内化潜力但无临床里程碑。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5504", "id": "d57M_5wBZznHJdnt_W7P", "source_drug_name": "a novel anti-hHER2 antibody-drug conjugate", "title": "A fast and robust development process providing new highly internalized anti-hHER2 antibody-drug conjugates", "abstract_text": "Purpose: The aim of this study was to establish an accelerated and de-risked workflow for the generation of potent anti-hHER2 antibody-drug conjugates (ADCs), addressing key bottlenecks that currently limit the efficiency, predictability, and overall success rate of ADC discovery.\nMethods: We implemented a fully integrated four-step strategy. (1) A multisite immunization protocol was developed to rapidly induce robust anti-hHER2 responses, enabling the isolation of high-titer antibodies in less than two weeks; antibodies generated with this accelerated protocol were benchmarked against a classical schedule. (2) Antibody-secreting plasma cells were isolated and ranked on the Bruker Beacon single-cell platform based on antigen binding and relative affinity prior to sequencing and recombinant expression. (3) A microscale, robotics-assisted production workflow was established to express and purify dozens of antibodies in parallel. Binding affinity was measured by bio-layer interferometry BLI, and internalization kinetics were quantified using a new lanthanide-based pH-sensitive probe. (4) A two-stage ADC synthesis pipeline was created using enzymatic conjugation and click chemistry. A first library of ADCs was generated by coupling 24 antibodies to MMAF at DAR4, followed by cytotoxicity assessment on patient-derived xenograft-derived cells (PDX-DC). The most promising hits were then reformatted into a second ADC library conjugated to multiple linker-payload combinations at diverse DARs with the same conjugation strategy.\nResults: The rapid immunization protocol consistently produced highly internalized anti-hHER2 antibodies, some surpassing those from classical schedule and trastuzumab. Beacon-based screening enabled efficient prioritization of clones with superior affinity. In the first ADC library, multiple candidates showed strong cytotoxic activity on PDX-DC models. Subsequent optimization through linker-payload engineering further enhanced potency for selected candidates.\nConclusions: This integrated and optimized workflow accelerates ADC generation from immunization to functional readout while reducing technical risk at each stage. It enabled the rapid identification of novel anti-hHER2 antibodies with enhanced internalization and highly potent ADC derivatives. This approach is broadly applicable to future ADC discovery programs targeting diverse antigens.", "source_company": "Mimabs", "source_org_type": "公司", "row_number": 1203, "target_meta": "HER2", "MOA_meta": "抗体偶联药物"}, {"drug_name": "MAb52-29.1-ADC", "company": "MedAbome, Inc.", "org_type": "公司", "target": "ALCAM (CD166)", "modality": "ADC", "importance_level": "中", "total_score": 63.5, "institution_score": 55, "track_score": 75, "milestone_score": 60, "field_heat_score": 65, "bonus_score": 3, "brief_reason": "靶点ALCAM（CD166）为肿瘤过表达的细胞黏附分子，药物为first-in-class anti-ALCAM ADC，机制新颖且肿瘤选择性高；MedAbome为美国preclinical-stage小biotech公司，非头部，ADC赛道热门但靶点非顶级热门，数据限于preclinical CDX模型有效，安全性初步良好。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4433", "id": "-J7M_5wBZznHJdnt_W3O", "source_drug_name": "MAb52-29.1-ADC", "title": "Preclinical efficacy of a first-in-class anti-ALCAM ADC in hard-to-treat solid and hematologic malignancies", "abstract_text": "ALCAM (CD166) is a type I transmembrane glycoprotein that mediates cell-cell adhesion through homophilic ALCAM-ALCAM and heterophilic ALCAM-CD6 interactions. ALCAM is aberrantly overexpressed across a variety of solid and hematologic malignancies. Using our proprietary live-cell immunization (LC-I) and high-throughput screening (LC-HTS) platforms, we developed MAb52-29.1, an anti-ALCAM monoclonal antibody that selectively recognizes a tumor-restricted conformational epitope of ALCAM, exhibiting minimal or no cross-reactivity with normal cells or tissues. Both the chimeric and humanized versions of MAb52-29.1 exhibited high binding affinities to recombinant ALCAM-ECD (KD ≈ 1.1 nM). MAb52-29.1 cAb, containing two point-mutations in each Fc, was conjugated to MMAE through an MC-Vc-PAB linker to produce MAb52-29.1-ADC (DAR4). MAb52-29.1-ADC demonstrated potent antiproliferative effects in vitro, with cytotoxicity correlating with its high antibody internalization efficiency in various cancer cell lines. Anti-tumor efficacy was demonstrated by a single intraperitoneal (i.p.) dose of MAb52-29.1-ADC at 4, 7, or 10 mg/kg using cell line-derived xenograft (CDX) mouse models of triple-negative breast cancer (TNBC), non-small cell lung cancer (NSCLC), gastric cancer (GC), and other tumor types, with subcutaneously inoculated tumors disappearing within 27~30 days after treatment. Preliminary toxicology studies indicated that MAb52-29.1-ADC did not raise any safety concerns. These findings support MAb52-29.1-ADC as a promising therapeutic candidate for treating solid and hematologic malignancies, and potentially mitigating toxicity concerns. Ongoing studies aiming to support further clinical investigation include MAb52-29.1-ADC in patient-derived xenograft (PDX) gastrointestinal (GI) cancer models, along with retrospective analyses of its target expression in clinical tumor samples.", "source_company": "MedAbome, Inc.", "source_org_type": "公司", "row_number": 1228, "target_meta": "ALCAM", "MOA_meta": "抗体偶联药物"}, {"drug_name": "MGT-1141", "company": "Marigold Therapeutics Inc", "org_type": "公司", "target": "DLL3", "modality": "ADC", "importance_level": "中", "total_score": 63.5, "institution_score": 45, "track_score": 90, "milestone_score": 65, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "MGT-1141为靶向DLL3的ADC，DLL3在SCLC和NECs中高表达且正常组织低表达，具有较好肿瘤选择性；公司为2024年底新成立的ADC专注biotech，处于早期阶段但IND-enabling研究进行中，preclinical数据强劲包括PDX模型有效和良好耐受性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4048", "id": "757M_5wBZznHJdnt_W3O", "source_drug_name": "MGT-1141", "title": "MGT-1141, an antibody-drug-conjugate targeting DLL3 positive cancers", "abstract_text": "Background: Delta-like ligand 3 (DLL3) is highly expressed on the cell surface of small cell lung cancer (SCLC) and neuroendocrine cancers (NECs)—among the most lethal malignancies—but is minimally or not expressed in normal tissues, making it an attractive target for DLL3-positive cancers. Here, we describe the preclinical activity of MGT-1141, an anti-DLL3 antibody-drug conjugate (ADC) that delivers a topoisomerase I inhibitor (exatecan) payload via Marigold’s proprietary linker platform. The IND-enabling study of MGT-1141 is currently ongoing.\nMethods: Comprehensive in vitro and in vivo evaluations were performed to characterize MGT-1141. Binding affinity, internalization, and cytotoxicity were examined across multiple DLL3-expressing cell lines. Anti-tumor efficacy was assessed in both cell line-derived xenograft (CDX) and patient-derived xenograft (PDX) models. Pharmacokinetic (PK) and pilot dose-range-finding (DRF) studies were conducted in cynomolgus monkeys to determine systemic exposure, half-life, and tolerability.\nResults: The MGT-1141 antibody exhibited high target specificity with no detectable cross-reactivity toward other Delta-like ligand family proteins. MGT-1141 demonstrated strong binding affinity and rapid internalization in DLL3-expressing cells. In vivo, MGT-1141 showed potent and dose-dependent tumor growth inhibition across multiple CDX and PDX models, with a minimal efficacious dose (MED) of 0.5 mg/kg. Pharmacokinetic studies in cynomolgus monkeys revealed linear, dose-proportional exposure and a favorable terminal half-life. Dose-range finding (DRF) studies indicated good tolerability and a wide therapeutic window.\nConclusion: Preclinical evaluations of MGT-1141 have shown potent and selective anti-tumor activity, favorable pharmacokinetic properties, and a well-tolerated safety profile, supporting its further development toward clinical investigation. Collectively, these findings support MGT-1141 as a promising and potential best-in-class DLL3-targeting ADC for the treatment of SCLC and NECs.", "source_company": "Marigold Therapeutics Inc", "source_org_type": "公司", "row_number": 1259, "target_meta": "DLL3", "MOA_meta": "抗体偶联药物"}, {"drug_name": "KY102", "company": "Hangzhou Kunyu Pharmaceutical", "org_type": "公司", "target": "GPC3", "modality": "NDC", "importance_level": "中", "total_score": 63, "institution_score": 45, "track_score": 85, "milestone_score": 65, "field_heat_score": 75, "bonus_score": 3, "brief_reason": "KY102为靶向GPC3的nanobody-drug conjugate (NDC)，负载拓扑异构酶1抑制剂DXD，在HCC模型中显示强效抗肿瘤活性及旁观者效应。机构为国内新兴biotech公司非头部，赛道ADC类热门但NDC亚类稍逊，preclinical数据扎实并计划2026年IND，总分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5433", "id": "NlXM_5wBX1NQZOEH-LS6", "source_drug_name": "KY102", "title": "KY102, a novel Glypican 3-targeting nanobody drug conjugate bearing a topoisomerase 1 inhibitor payload demonstrates compelling preclinical activity in hepatocellular carcinoma models", "abstract_text": "Background: Glypican-3(GPC3), a cell-surface oncofetal glycoprotein highly expressed in hepatocellular carcinoma (HCC) with minimal presence in normal adult tissues. KY102 is a nanobody-drug conjugate (NDC)targeting human GPC3, composed of a monovalent nanobody covalently conjugated to a topoisomerase 1 inhibitor, DXD. via a maleimide anchor and a glycyl glycyl phenylalanyl glycine (GGFG)- aminomethyl (AM) cleavable linker at a drug to nanobody ratio (DAR) of 3.\nMaterials and Methods: Extensive functional characterization was performed to assess the mechanism of action and therapeutic potential of the KY102 (NDC) at DARs of 3.\n1.Nanobody binding to human,cynomolgus monkey rat and mouse GPC3 was assessed by biolayer interferometry (BLI) and flow cytometry(FACs).\n2.Am assessment of off-target binding, and target specificity was conducted using 177-Lu labeled Nanobody in normal and cell line derived animalmodel.\n3.KY102 nanobody internalization in GPC3-expressing tumor cell lines was assessed by flow cytometry.\n4.In vitro KY102 (NDC) cytotoxicity against tumor monolayers was assessed in a panel of HCC cell lines.\n5.Tumor cell co-culture assays were also performed to assess bystander-mediated cell killing by KY102.\n6.Anti-tumor activity of KY102 was investigated in a panel of cell line-derived xenograft (CDX) and patient-derived xenograft (PDX) mouse models representing a range of GPC3 expression.\n7.The tolerability of KY102 was assessed in a single dose and repeat-dose (4 doses; once every weeks) non-GLP toxicology study in a cell line-derived xenograft (CDX) in mice.\nResults:\n1.The KY102 nanobody backbone demonstrated pico-molar binding affinity to both human, cynomolgus monkey, rat and mouse GPC3, and strong binding to target-expressing cancer cell lines.\n2.Rapid internalization of KY102 nanobody was observed in GPC3-expressing HCC cell lines.\n3.KY102 exhibited potent and target-specific cytotoxicity in a panel of HCC cells cultured either in monolayer.\n4.KY102 showed effective bystander-mediated killing of GPC3 negative cancer cells when in co-culture with GPC3 positive cancer cells.\n5.A single administration of KY102 ( 2.5mg/kg and 5.0 mg/kg) resulted in robust tumor growth inhibition of a panel of CDX and PDX models representing a range of GPC3-expression.\n6.A single dose and a repeat-dose mouse toxicology study of KY102 showed encouraging tolerability at 30, and 60 mg/kg dose levels.\n7.A dose-dependent nanobody pharmacokinetics at 2.5 mg/kg, and 5 mg/kg dose levels, without the maximum tolerated dose (MTD) determined.\nConclusions: Overall, these results support the potential of KY102 as a novel therapeutic agent against GPC3-bearing cancers including HCC. An IND application is anticipated in 2026. No conflict of interest", "source_company": "Hangzhou kunyu pharmaceutical", "source_org_type": "公司", "row_number": 130, "target_meta": "GPC3", "MOA_meta": "其他"}, {"drug_name": "TWQ-184", "company": "Stanford University", "org_type": "大学", "target": "BRD4-NUT fusion oncoprotein", "modality": "other", "importance_level": "中", "total_score": 63, "institution_score": 40, "track_score": 85, "milestone_score": 70, "field_heat_score": 80, "bonus_score": 8, "brief_reason": "TWQ-184为双功能分子，通过劫持BRD4-NUT融合癌蛋白诱导PARP介导的DNA损伤和程序性细胞死亡，针对罕见但极度恶性的NUT癌表现出极高体外效能和选择性。斯坦福大学学术机构基础分较低，但创新性DD-CIPs策略结合融合癌蛋白靶向+热门DNA损伤机制及preclinical强数据，赛道与bonus亮点突出，综合潜力中等偏上。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1810", "id": "CFXM_5wBX1NQZOEH-LK6", "source_drug_name": "TWQ-184", "title": "Hijacking the BRD4-NUT fusion oncoprotein to activate programmed cell death", "abstract_text": "Fusion oncogenes account for about 10-20% of all cancer drivers and generally result from in-frame recombination with specific partners. Cancers driven by fusion oncogenes often occur in young people whose genomes are relatively free of other mutations, providing a singular reliance on the fusion and its underlying mechanisms. Despite this focus, fusion oncogenes — particularly those that arise from transcription factors — have been difficult to target therapeutically. We demonstrate in this study that the fusion oncoprotein BRD4-NUT can be used to specifically activate programmed cell death in an aggressive form of squamous cancer, NUT carcinoma (NC). NC is caused by a translocation of the NUTM1 gene downstream of the BRD4 gene. Transcription of the fusion gene is therefore controlled by the BRD4 regulatory region, leading to high-level expression of the fusion oncoprotein. The NUT protein is normally restricted to the testes, where it is essential for histone hyperacetylation, histone removal and replacement by protamines. NC currently has a mean‬‭ survival of 6-9 months and no approved treatments. We reasoned that the oncogenic program of BRD4-NUT could be reprogrammed to activate a synthetic death circuit. To selectively inhibit NC, we developed bifunctional molecules that target the BRD4-NUT fusion, BRD4 and PARP. We call the new class of molecules DD-CIPs for DNA Damage-Chemical Inducers of Proximity. The most potent member of this new class (TWQ-184) kills NC cell lines (10-15, SW and 14169) at concentrations between 0.74 nM and 6 nM. TWQ-184 forms a ternary complex with BRD4-NUT and PARP, resulting in cell death. P300 inhibitors partially rescue NC cells from TWQ-184-induced apoptosis, suggesting that transcription at PARP-bound DNA breaks driven by BRD4-NUT is required to initiate cell death. TWQ-184 induces γH2AX deposition and ATM activation within 24 hours, suggesting that PARP-bound single-strand breaks are converted to lethal double-strand breaks in the cancer cells. Exposure to TWQ-184 for one hour gives near-complete NC death at 72 hours, suggesting that intermittent dosing might be effective. TWQ-184 additionally exhibits high specificity for the malignant cells, evidenced by the substantial therapeutic windows between NC cell lines and healthy human lymphocytes and fibroblasts. Based on our current findings, the compound’s high efficacy in the cancer cells and low toxicity in healthy cells offer a promising approach to treat NC. This strategy for hijacking a fusion oncoprotein to activate transcriptionally coupled DNA damage-mediated cell death could be applicable to other transcriptional fusion oncogenes.‬‬‬", "source_company": "Stanford University", "source_org_type": "大学", "row_number": 496, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "SCRI-6", "company": "Seattle Children's Research Institute", "org_type": "研究机构", "target": "CD3δε", "modality": "TCE", "importance_level": "中", "total_score": 63, "institution_score": 45, "track_score": 85, "milestone_score": 65, "field_heat_score": 80, "bonus_score": 4, "brief_reason": "SCRI-6为新型非多反应性CD3δε选择性结合物，用于TCE可显著降低细胞因子释放并维持抗瘤活性，同时安全兼容共刺激设计。机构为研究机构得分一般，但TCE+新型CD3优化在实体瘤领域具有较高赛道热度和临床潜力。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4487", "id": "5lXM_5wBX1NQZOEH-LO6", "source_drug_name": "SCRI-6", "title": "Novel CD3 binders enable T cell engagers with potent tumor control, limited cytokine release, and safe pairing with co-stimulation", "abstract_text": "Introduction: T cell engagers (TCEs) have demonstrated clinical promise in hematologic malignancies, but their application in solid tumors has been held back by significant side effects and limited efficacy. TCEs that bind CD3 with SP34-derived clones exhibit marked polyreactivity, leading to off-target activation and narrow therapeutic windows. Leveraging a unique nanoparticle-based immunization platform, we discovered non-polyreactive, non-human primate (NHP) cross-reactive CD3 binders, many against novel CD3 epitopes. As exemplified by a CD3δε selective clone, SCRI-6, these binders drive potent anti-tumor activity with reduced cytokine production. Our data suggests that these novel binders are uniquely positioned to pair with TCE designs that incorporate costimulation strategies to improve T cell antitumor activity and persistence.\nMethods: Our antibody campaign used a novel immunization strategy in the OmniRat transgenic platform incorporating whole-cell and protein-nanoparticle immunogens. Identified hits from the campaign were produced as recombinant monoclonal antibodies and biochemically and biophysically characterized. Clinical benchmark TCEs incorporating our novel CD3 binders were evaluated for non-specific activation, antigen-dependent tumor-cell killing and cytokine release in vitro and in vivo.\nResults: We identified 12 distinct sequence families, 7 of which bound and activated human T cells. Among these, 5 showed no detectable polyreactivity. Four clones recognized both CD3δε and CD3γε subunits, whereas one clone (SCRI‑6) bound exclusively to CD3δε. Notably, 3 of these sequence families, including SCRI‑6, also activated NHP T cells. TCEs (targeting PD-L1, DLL3, and CD19) that incorporate our novel CD3 binders demonstrated antigen-dependent cytotoxicity comparable to SP34-based TCEs but with reduced cytokine release (e.g., IFNγ, IL-2, TNFα, and IL-6). In an assay to assess tumor-independent activation of T cells, TCEs including SCRI-6 exhibit dramatically less non-specific T cell activation than matched-TCEs containing SP34. Adding CD28 or 4-1BB costimulation to this assay dramatically exacerbated the non-specific activation caused by SP34-containing TCEs; however, swapping the CD3 binder for SCRI-6 eliminated this activity. TCEs incorporating SCRI-6 demonstrate equivalent potency to clinical benchmark comparators in both solid and liquid in vivo tumor models, but with substantially lower cytokine release.\nConclusion: Non-polyreactive CD3 engagers may be incorporated into TCEs to improve therapeutic index without sacrificing potency and allowing for therapeutic strategies that safely engage T cell costimulatory targets.", "source_company": "Seattle Children's Research Institute", "source_org_type": "研究机构", "row_number": 813, "target_meta": "CD3δ,CD3ε", "MOA_meta": "其他"}, {"drug_name": "177Lu-KBD880", "company": "Kangbaida (Sichuan) Biopharmaceutical Technology Co., Ltd", "org_type": "公司", "target": "GPC3", "modality": "RLT imaging agent", "importance_level": "中", "total_score": 62.5, "institution_score": 45, "track_score": 85, "milestone_score": 65, "field_heat_score": 75, "bonus_score": 3, "brief_reason": "药物为靶向GPC3的177Lu标记放射性多肽偶联物，用于HCC的放射性药物治疗，具有高亲和力和良好体内分布及显著肿瘤抑制效果。机构为国内中小型biotech（成都百裕子公司），赛道为热门RLT领域但preclinical阶段，综合潜力中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6438", "id": "2VXM_5wBX1NQZOEH-LG6", "source_drug_name": "177Lu-KBD880", "title": "KBD880 is a potent and selective GPC3 peptide binder for treatment of HCC", "abstract_text": "Background: The membrane-associated glycoprotein Glypican-3 (GPC3) is highly overexpressed in hepatocellular carcinoma (HCC) while exhibiting minimal to no expression in normal tissues. This tumor-specific expression profile makes GPC3 an ideal target for developing radiopharmaceutical therapies to treat HCC, a leading cause of cancer-related deaths worldwide.\nMethods: DOTA-KBD-GPC3 (KBD880) is a radiopharmaceutical conjugate composed of a novel GPC3-binding macrocyclic peptide, a linker, and a DOTA chelator for complexation with therapeutic radioisotopes. The binding affinity of the 175Lu-labeled conjugate was characterized by surface plasmon resonance and competitive flow cytometry. Subsequently, Target-mediated cellular internalization kinetics were quantified via radiometric assays. In vivo, the biodistribution and therapeutic efficacy of the 177Lu-labeled conjugate were evaluated in HepG2 HCC xenograft model.\nResults: 175Lu-KBD880 exhibited high-affinity binding to both human and murine GPC3, with equilibrium dissociation constants (KD) of 2.20 nM and 2.02 nM, respectively, as determined by surface plasmon resonance. In addition, 175Lu-KBD880 showed potent binding to GPC3-expressing HepG2 cells (IC50= 9.3 nM). A high proportion of non-canonical amino acids and fragments with favorable drug-like properties were used to achieve a balance of potency, permeability, and physicochemical properties. 175Lu-KBD880 exhibited excellent permeability, an optimal half-life and substantial systemic exposure in mice. The therapeutic conjugate, 177Lu-KBD880, exhibited rapid and efficient internalization, achieving cellular uptake ratios of 50-60%. 177Lu-KBD880 displayed an excellent in vivo profile, characterized by high tumor retention, rapid renal clearance, and minimal off-target uptake. This favorable biodistribution translated into significant and sustained tumor growth inhibition following monotherapy in GPC3-positive HCC xenografts.\nConclusions: KBD880 is a potent and selective, peptide-based radiopharmaceutical agent developed for targeting GPC3-expressing tumors. Its favorable preclinical characteristics—including an optimal pharmacokinetic profile, targeted biodistribution, and durable monotherapy efficacy—strongly support its development as a theranostic agent for patients with GPC3-positive malignancies.", "source_company": "Kangbaida (Sichuan) Biopharmaceutical Technology Co., Ltd", "source_org_type": "公司", "row_number": 127, "target_meta": "GPC3", "MOA_meta": "其他"}, {"drug_name": "CAN016", "company": "Canwell Biotechnology Company", "org_type": "公司", "target": "HER2", "modality": "ADC", "importance_level": "中", "total_score": 62.5, "institution_score": 45, "track_score": 85, "milestone_score": 65, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "CAN016为HER2靶向的双payload ADC（MMAE+exatecan），采用新型StarLinker平台，旨在克服Enhertu耐药。机构为中国新兴biotech，得分中等；ADC+HER2+双负载赛道热门且有明确Phase 1进展及抗耐药亮点，综合热度较高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/12222", "id": "UFXM_5wBX1NQZOEH-LS6", "source_drug_name": "CAN016", "title": "CAN016, a HER2-targeted dual-payload ADC, phase 1 clinical development", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Canwell Biotechnology Company", "source_org_type": "公司", "row_number": 145, "target_meta": "HER2", "MOA_meta": "抗体偶联药物"}, {"drug_name": "anti-PD-1", "company": "UT MD Anderson Cancer Center", "org_type": "医院", "target": "PD-1", "modality": "inhibitor", "importance_level": "中", "total_score": 62.5, "institution_score": 45, "track_score": 85, "milestone_score": 65, "field_heat_score": 80, "bonus_score": 2, "brief_reason": "anti-PD-1为经典免疫检查点抑制剂，靶向PD-1，在摘要中用于联合NET抑制显示增强tsMHC-ILow肿瘤控制。机构为顶级癌症中心但非药企导致institution_score较低，赛道为成熟热门免疫治疗+新机制轴（tsMHC-I-NET）潜力较高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1405", "id": "D1XM_5wBX1NQZOEH-LG5", "source_drug_name": "anti-PD-1", "title": "Spatiotemporal analysis reveals tsMHC-I downregulation-induced neutrophil extracellular traps as a driver of lung adenocarcinoma neoplastic evolution", "abstract_text": "Background:Loss of tumor-specific MHC class I (tsMHC-I) is a recurrent feature of lung adenocarcinoma (LUAD) progression and is associated with immune escape and poor outcomes. However, how tsMHC-I downregulation shapes tumor evolution and remodels the immune microenvironment remains unclear.\nMethods:We integrated single-cell RNA sequencing, spatial transcriptomics, and multiplex imaging from human LUAD samples spanning precancerous lesions to advanced tumors, together with longitudinal genetically engineered mouse models (GEMMs). Functional assays—including neutrophil co-culture, assessment of neutrophil extracellular traps (NETs), and in vivo tumor studies—were performed to define mechanistic consequences of tsMHC-I loss.\nResults:Progressive tsMHC-I downregulation was observed across LUAD evolution and validated in GEMMs. Single-cell trajectory analysis showed that reduced tsMHC-I is linked to loss of alveolar type II identity, increased chromosomal instability, heightened tumor plasticity, and acquisition of epithelial-mesenchymal transition (EMT) programs. Functionally, tsMHC-ILow malignant cells displayed increased invasiveness and metastatic capacity. Spatial and immunophenotypic profiling revealed that tsMHC-I downregulation reshapes the tumor microenvironment toward a neutrophil-enriched, cytotoxic cell-excluded niche. tsMHC-ILow regions exhibited dense tumor-associated neutrophil aggregates and depletion of CD8⁺ T cells, NK cells, and other effector populations. Mechanistic studies showed that tsMHC-ILow malignant cells induce robust NET formation. In vitro assays identified Annexin A2, a tumor-secreted protein, as a key driver of NET induction. Annexin A2 expression and secretion were consistently elevated in tsMHC-ILow cells across human and mouse models, and Anxa2 knockdown markedly reduced NET formation. Targeting NETs in vivo with DNase I selectively suppressed growth and metastatic spread of tsMHC-ILow tumors, restored cytotoxic immune infiltration, and reversed the immune-excluded phenotype. In tsMHC-I heterogeneous tumors, combining NET inhibition with anti-PD-1 enhanced tumor control and survival.\nConclusions:Our integrated analyses reveal that tsMHC-I downregulation drives neutrophil recruitment and NET formation through Annexin A2 secretion, creating an immunosuppressive barrier that promotes LUAD progression and limits immunotherapy response. These findings identify a previously unrecognized tsMHC-I-NET axis as a therapeutic vulnerability in LUAD.", "source_company": "UT MD Anderson Cancer Center", "source_org_type": "医院", "row_number": 320, "target_meta": "PD1", "MOA_meta": "抑制剂"}, {"drug_name": "JHU12-TCR2", "company": "Johns Hopkins University", "org_type": "大学", "target": "DNAJ-PKAc", "modality": "TCR", "importance_level": "中", "total_score": 62.5, "institution_score": 45, "track_score": 85, "milestone_score": 70, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "JHU12-TCR2为针对DNAJ-PKAc融合蛋白的新抗原特异性CD4+ TCR，用于TCR工程化细胞治疗，靶向罕见肝癌FLC的独特驱动融合。机构为顶尖大学而非商业公司得分中等，TCR细胞治疗赛道及罕见癌未满足需求热度高，摘要显示强功能活性+临床前优异表现+患者近完全缓解相关，正在开发临床试验，故综合为中重要性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5230", "id": "eVXM_5wBX1NQZOEH-LO6", "source_drug_name": "JHU12-TCR2", "title": "Development of T cell receptor (TCR) based cellular therapy for fibrolamellar HCC uncovers role of TCR in CD4 T cell differentiation", "abstract_text": "Background: Fibrolamellar carcinoma (FLC) is a rare and often lethal liver cancer that primarily affects children and young adults. There is no approved systemic therapy for FLC. The FLC transcriptome is defined by an in-frame fusion of exon 1 of DNAJB1 with exons 2-10 of PRKACA, resulting in expression of the chimeric oncoprotein DNAJ-PKAc. Direct pharmacologic inhibition of this oncoprotein has been infeasible due to unacceptable on-target toxicity. However, the shared, tumor-specific expression of DNAJ-PKAc presents an opportunity for neoantigen-targeted immunotherapy.\nMethods: We are conducting an ongoing clinical trial of a peptide vaccine targeting DNAJ-PKAc in combination with immune checkpoint inhibitors. We used single-cell sequencing and functional assays to identify DNAJ-PKAc-specific T cell receptors (TCRs) from peptide-expanded peripheral blood cells of trial participants. We characterized their HLA restriction, avidity, cytotoxicity, cytokine profiles, and differentiation phenotypes using co-culture systems.\nResults: We identified seven CD4⁺ TCRs that recognize DNAJ-PKAc in the context of HLA-DRB1*13:01 (n=2) or HLA-DRB3*01:01 (n=5). When introduced into healthy donor T cells and co-cultured with tumor cells expressing the corresponding HLA allele, these TCRs exhibited variable functional avidity, cytokine production, differentiation, and cytotoxic activity against DNAJ-PKAc-pulsed targets. Among them, JHU12-TCR2 (HLA-DRB3*01:01-restricted) mediated the strongest cytokine production and tumor cell killing despite only moderate avidity. Consistent with this, JHU12-TCR2 showed the greatest in vivo expansion in the original patient, who achieved a near-complete response to immunotherapy. In contrast, a fusion-specific TCR identified from a non-responder, JHU8-TCR2, that shares sequence similarities and clusters with JHU12-TCR2, demonstrated limited cytotoxicity in vitro. Interestingly, although all TCRs recognized the same antigen in matched donor T cells, they drove divergent helper T cell differentiation programs. For example, JHU12-TCR2 favored Th1/Th17 polarization with minimal Treg induction, whereas JHU8-TCR2 promoted a Th2-biased phenotype.\nConclusions: We identified and functionally characterized multiple CD4⁺ TCRs specific for the DNAJ-PKAc oncoprotein, highlighting their potential utility as the basis for TCR-based therapy in FLC. A clinical trial of JHU12-TCR2-based TCR therapy for patients with FLC and HLA-DRB3*01:01 is in development. These findings also suggest that variation in vaccine-induced TCR repertoires may contribute to differences in clinical response, and that intrinsic biophysical or signaling properties of individual TCRs can shape the differentiation fate of CD4⁺ T cells expressing them.", "source_company": "Johns Hopkins University\nJOHNS HOPKINS UNIVERSITY", "source_org_type": "大学", "row_number": 730, "target_meta": "not available", "MOA_meta": "TCR"}, {"drug_name": "semi-replicating retroviral vector (sRRV) platform", "company": "Articure", "org_type": "公司", "target": "未披露", "modality": "other", "importance_level": "中", "total_score": 62.5, "institution_score": 45, "track_score": 75, "milestone_score": 80, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "该sRRV平台为新型稳定双自杀基因递送系统，针对胶质母细胞瘤实现肿瘤选择性复制和协同杀伤，未明确具体靶点。机构为小型韩国biotech公司得分一般，但平台解决重组难题、在免疫完整和缺陷模型中显示完全肿瘤清除的强效preclinical数据，基因治疗+自杀基因赛道在脑瘤领域有较高潜力。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10431", "id": "a57ECZ0BZznHJdntvNYd", "source_drug_name": "semi-replicating retroviral vector (sRRV) platform", "title": "Overcoming recombination in semi-replicating retroviral vectors: A novel double suicide gene therapy for glioblastoma", "abstract_text": "One of the longstanding challenges in developing semi-replicating retroviral vector (sRRV) systems has been the loss of therapeutic genes due to non-homologous recombination during reverse transcription in dividing tumor cells. To address this, we developed a genetically stabilized sRRV platform capable of efficient combinatorial gene therapy, preserving the integrity of multiple therapeutic genes while replicating and spreading exclusively within tumors. Our system consists of two trans-complementing, replication-defective retroviral vectors: one encoding MuLV-Gag-Pol and cytosine deaminase (CD), and the other encoding GaLV-Env and HSV1-thymidine kinase (TK). These vectors co-infect tumor cells and propagate selectively within the tumor microenvironment. By eliminating homologous sequences between vectors, we achieved a recombination-resistant design, ensuring long-term genetic stability during serial replication. The antitumor efficacy of this platform was validated in two glioblastoma models. First, in a syngeneic rat orthotopic glioma model, C6 glioma cells were implanted intracranially into Wistar rats.The therapeutic vectors were directly injected into the tumor site, followed by systemic administration of prodrugs 5-fluorocytosine (5-FC) and ganciclovir (GCV). Histological analysis on day 98 revealed dose-dependent tumor regression, with complete tumor eradication in the high-dose, dual-prodrug cohort. Survival analysis confirmed significantly extended survival in treated groups. Second, in an intracranial xenograft model using athymic nude mice, human glioma cells were implanted in the brain parenchyma, followed by stereotactic delivery of the sRRV vectors and systemic prodrug treatment. Remarkably, complete tumor remission was again observed in the combination treatment group, despite the absence of adaptive immunity, highlighting the platform's intrinsic efficacy. Analysis of vector genomes recovered from tumor tissues revealed no evidence of recombination or gene loss, confirming the system’s robust genetic stability. The vectors maintained persistent coexpression of both therapeutic genes, which are essential for synergistic prodrug activation and tumor cell killing. In conclusion, this study presents a next-generation sRRV platform that resolves a major technical barrier—recombination-mediated gene loss—while enabling stable and tumor-selective delivery of multiple therapeutic genes. Its potent efficacy in both immunocompetent and immunodeficient brain tumor models, including intracranial xenografts, positions it as a promising candidate for clinical translation in glioblastoma and other refractory solid tumors.", "source_company": "Articure", "source_org_type": "公司", "row_number": 847, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "trastuzumab bromoseradeg", "company": "Baylor College of Medicine", "org_type": "大学", "target": "HER2", "modality": "ADC", "importance_level": "中", "total_score": 62.5, "institution_score": 35, "track_score": 85, "milestone_score": 75, "field_heat_score": 80, "bonus_score": 8, "brief_reason": "药物为HER2靶向ADC，创新性地以共价BRD4分子胶降解剂bromoseradeg作为payload，可克服T-DXd常见耐药机制（TOP1突变和ABCC1外排）。机构为大学得分较低，但赛道（新一代ADC+热门BRD4降解）和克服临床耐药的强preclinical数据带来较高综合价值。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6483", "id": "Q1XM_5wBX1NQZOEH-LO6", "source_drug_name": "trastuzumab bromoseradeg", "title": "A novel covalent BRD4 degrader-HER2-targeting antibody-drug conjugate (DAC) overcomes trastuzumab deruxtecan resistance in HER2-positive cancers", "abstract_text": "Trastuzumab deruxtecan (T-DXd), an antibody drug conjugate (ADC), has transformed the treatment landscape for HER2-positive cancers. However, its long-term efficacy is limited by the inevitable development of resistance, which is often driven by altered internalization dynamics, impaired payload activation, or drug efflux. Therefore, next-generation ADCs capable of overcoming these resistance mechanisms are urgently needed to extend durable benefit. We have developed a next-generation degrader antibody conjugate (DAC) that combines a HER2 targeting antibody, trastuzumab, and a selective BRD4 molecular glue degrader, bromoseradeg (BsD), as the payload. BsD is a highly potent, covalent BRD4 degrader and exhibits single digit nanomolar (nM) or sub-nM potency across diverse HER2+ cancer models. Trastuzumab bromoseradeg (T-BsD) was synthesized by cysteine conjugation chemistry via the cleavable Valine-Citrulline-para-aminobenzyl carbamate (Val-Cit-PABC; VCP) linker with an average drug-to-antibody ratio (DAR) of ~4. T-BsD preserved strong Her2-dependent cytotoxicity and consistently outperforming T-DXd in multiple HER2+ cell models and is also highly active in the T-DXd-insensitive xenograft model. To directly interrogate different resistance mechanisms, we first engineered HER2⁺ cancer lines to carry the clinically relevant TOP1 R364H mutation, which abolishes TOP1 inhibitor binding and confers robust T-DXd resistance. T-BsD retained cytotoxic potency in these mutant cells ex vivo and showed no loss of antitumor activity in corresponding xenograft models. Separately, we also evaluated resistance driven by overexpression of the efflux transporter ABCC1, a common mechanism that exports the DXd payload. In HER2⁺ cells with high ABCC1 expression, T-Dxd activity was abrogated, whereas T-BsD completely bypassed ABCC1-mediated efflux and maintained potent activity in both 2D culture and 3D xenograft tumors. Collectively, these compelling preclinical findings establish T-BsD as a mechanistically distinct therapeutic agent designed to overcome potentially key drivers of acquired resistance. By integrating potent BRD4 degradation with HER2-targeted delivery, T-BsD achieves superior activity and effectively bypasses the two most clinically relevant T-DXd resistance pathways. Together, these data strongly support the selective BRD4 degrader as a promising payload for developing next-generation ADCs that can benefit patients who are refractory or resistant to current ADC therapies.", "source_company": "Baylor College of Medicine", "source_org_type": "大学", "row_number": 1279, "target_meta": "HER2", "MOA_meta": "抗体偶联药物"}, {"drug_name": "ATZ-IEP complex", "company": "Peptron, Inc.", "org_type": "公司", "target": "PD-L1", "modality": "other", "importance_level": "中", "total_score": 62, "institution_score": 55, "track_score": 85, "milestone_score": 45, "field_heat_score": 75, "bonus_score": 5, "brief_reason": "ATZ-IEP complex利用internalization-enhancing peptide (IEP)促进抗PD-L1抗体介导的PD-L1溶酶体降解，属于新型TPD平台；Peptron为韩国中小型biotech公司（非头部），赛道为新兴lysosomal degradation TPD有较高热度，但仅preclinical体外数据，无清晰临床里程碑。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6556", "id": "357M_5wBZznHJdnt_W3O", "source_drug_name": "ATZ-IEP complex", "title": "A novel targeted protein degradation platform based on internalization-enhancing peptide for lysosomal degradation of cell-surface proteins", "abstract_text": "Targeted protein degradation (TPD) is an emerging therapeutic approach that enables the selective elimination of undesirable proteins with high specificity. Although TPD holds great promise for targeting traditionally undruggable proteins and overcoming resistance often seen with inhibition-based therapies, several challenges remain, including suboptimal pharmacokinetics, limited internalization, and the dependency on E3 ligases or lysosome-targeting receptors. Here, we present a novel TPD platform based on internalization-enhancing peptide (IEP). IEP binds tightly yet non-covalently to antibodies (Abs) without altering their structure and enhances Ab internalization. We hypothesized that IEP could promote lysosomal degradation of cell-surface proteins by facilitating internalization. To demonstrate its potential, Atezolizumab (ATZ), an FDA-approved monoclonal antibody targeting PD-L1, was used as a model. Since ATZ alone does not strongly induce PD-L1 internalization, it provides an ideal system to test IEP-mediated degradation. Indeed, PD-L1 protein levels were markedly reduced in MDA-MB-231 (TNBC) cells treated with ATZ-IEP (a non-covalent ATZ/IEP complex), whereas no reduction was observed with ATZ or IEP alone. The decrease in PD-L1 was blocked by BafA1, a lysosomal proteolysis inhibitor, but not by MG132, a proteasome inhibitor—indicating that ATZ-IEP mediates lysosomal, rather than proteasomal, degradation. To assess the generality of this effect, Durvalumab (DUR), another FDA-approved anti-PD-L1 antibody, and HCC827 (NSCLC) cells were tested. PD-L1 levels were reduced with DUR-IEP (a non-covalent DUR/IEP complex) to a similar extent as with ATZ-IEP, and ATZ-IEP also decreased PD-L1 expression in HCC827 cells, comparable to the effect observed in MDA-MB-231 cells. These results indicate that IEP functions broadly across different antibodies and tumor types. Intriguingly, using transgenic CHO cell lines with varying PD-L1 expression, we found that the extent of PD-L1 reduction increased as baseline PD-L1 expression decreased (~70 % in PD-L1Low vs. ~20 % in PD-L1High). This finding suggests that IEP may help overcome anti-PD-L1 resistance in tumors with low PD-L1 expression. In summary, ATZ-IEP mediates lysosomal degradation of PD-L1 and demonstrates broad applicability across antibodies and tumor types. Ongoing in vivo studies aim to confirm the efficacy of ATZ-IEP, further supporting the versatility of IEP as a novel TPD platform.", "source_company": "Peptron, Inc.", "source_org_type": "公司", "row_number": 90, "target_meta": "PDL1", "MOA_meta": "其他"}, {"drug_name": "MMAE conjugated EGFR targeted antibody-drug conjugate", "company": "Thermo Fisher Scientific", "org_type": "公司", "target": "EGFR", "modality": "ADC", "importance_level": "中", "total_score": 62, "institution_score": 65, "track_score": 85, "milestone_score": 40, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "药物为EGFR靶向的MMAE ADC，ADC赛道和EGFR靶点在肿瘤治疗中热度高，但Thermo Fisher作为科研工具和服务公司而非核心药物研发MNC/biotech，开发处于工具验证/preclinical筛选阶段，无明确临床里程碑。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5427", "id": "uVXM_5wBX1NQZOEH-LO6", "source_drug_name": "MMAE conjugated EGFR targeted antibody-drug conjugate", "title": "Next generation molecular tools for evaluating antibody drug conjugates in 3D systems", "abstract_text": "The development of effective anti-cancer drugs relies on accurately evaluating therapeutic antibodies. Three-dimensional (3D) tumoroids, which closely mimic the tumor microenvironment, help provide a promising platform for these evaluations. Our research focuses on validating therapeutics using antibody degradation trackers and antibody drug conjugates within 3D tumoroids. LysoLight tagged antibodies are fluorogenic in lysosomes, allowing visualization of antibody behavior within tumoroids, enabling insights into antibody degradation. Our studies showed higher Cetuximab uptake and localization to lysosomes in EGFR-overexpressing lung adenocarcinoma tumoroids, while non-specific antibodies or EGFR-null tumoroids showed minimal LysoLight activity. Additionally, we generated MMAE conjugated therapeutic antibodies using the new SiteClick rapid antibody conjugation technique, that allowed rapid screening of candidates from selected monoclonal antibodies to identify candidates with favorable therapeutic potential. High-throughput assays within 3D tumoroids enabled us to evaluate binding affinity, internalization rates, and cytotoxic effects. Our findings indicated that a MMAE conjugated EGFR targeted antibody-drug conjugate, facilitated a targeted cell penetration of drugs in colon cancer tumoroids and induced cell death. Integrating antibody degradation trackers and high-throughput Ab screenings within 3D tumoroids offers a robust platform for evaluating therapeutic efficacy, by providing a more accurate representation of their behavior in vivo. Disclaimer: For Research Use Only. Not for use in diagnostic procedures. © 2025 Thermo Fisher Scientific Inc. All rights reserved. All trademarks are the property of Thermo Fisher Scientific and its subsidiaries unless otherwise specified.", "source_company": "Thermo Fisher Scientific", "source_org_type": "公司", "row_number": 777, "target_meta": "EGFR", "MOA_meta": "抗体偶联药物"}, {"drug_name": "TRIO-863", "company": "Purdue University", "org_type": "大学", "target": "CD33 和 TRAIL-R2", "modality": "bispecific antibody", "importance_level": "中", "total_score": 62, "institution_score": 35, "track_score": 85, "milestone_score": 75, "field_heat_score": 80, "bonus_score": 6, "brief_reason": "TRIO-863为首创CD33/TRAIL-R2双特异性抗体，通过双靶点限制性激活TRAIL通路选择性诱导AML细胞凋亡，机制新颖且显示对TP53突变及耐药模型的强效活性。大学机构得分较低，但热门双抗赛道+克服当前AML治疗痛点+较强的preclinical数据组合使其整体重要性达中等偏上。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5749", "id": "O57M_5wBZznHJdnt_W3O", "source_drug_name": "TRIO-863", "title": "A novel CD33 and TRAIL-R2 targeting bispecific antibody to treat relapsed/refractory acute myeloid leukemia", "abstract_text": "Acute myeloid leukemia (AML) remains a challenging disease due to poor survival and high relapse rates as current therapies lack selectivity: cannot eradicate leukemic blasts without causing immune and hematopoietic toxicity, resulting in severe toxicities and low efficacy. Furthermore, current therapies such as hypomethylating agents (HMA) and venetoclax (Ven) fail in patients with TP53 mutations. There is a critical need for therapies that can selectively eliminate leukemic cells while sparing normal hematopoiesis.TRIO-863 is a first-in-class CD33 and TRAIL-R2 targeting bispecific antibody designed to trigger apoptosis selectively in AML blasts through dual engagement of CD33 and TRAIL-R2. By binding CD33 with high affinity and restricting TRAIL-R2 activation to CD33+ cells, TRIO-863 confines apoptotic signaling to leukemic cells minimizing off-target effects. Potency, selectivity, and mechanism of action were evaluated in AML cell lines, including high-risk TP53-mutant and HMA/Ven-refractory patient samples. Safety was assessed ex vivo using human liver microtissue and immune cells.TRIO-863 showed potent CD33-dependent killing of AML cells including high risk TP53-mutant and drug-resistant models, with over 3700-fold greater potency than Mylotarg. It synergized with HMA/Ven and eliminated blasts ex vivo from AML patients who are relapsed/refractory, heavily pre-treated, with unfavorable genetic mutations – including high risk biallelic TP53 mutations. TRIO-863 also exhibited statistically significant and dose-dependent inhibition of TP53-mutant leukemic cell growth in a xenograft model. Anti- leukemic activity of TRIO-863 in vivo requires dual engagement of CD33 and TRAIL-R2 suggesting TRIO-863 remains intact in vivo as a stable drug. CFU assays with non-leukemic CD34+ progenitors from healthy donors demonstrated TRIO-863 spared normal hematopoietic stem and progenitor cells. In contrast, Mylotarg, a CD33-targeting ADC currently approved for use in fit AML patients, killed non-leukemic hematopoietic progenitor cells. Ex vivo safety studies using primary human liver microtissues showed no liver toxicity by TRIO-863 in contrast to monospecific anti-TRAIL-R2 antibodies that showed high toxicity in the assay. Mechanistic studies confirmed apoptosis depends on dual engagement, overcoming resistance from TP53 inactivation and MCL1 upregulation. CD33 and TRAIL-R2 expression will serve as biomarkers for patient selection; analysis of blasts of AML patients exposed to Ven/HMA and 7+3 confirmed expression of the receptors.TRIO-863 represents a mechanistic breakthrough in AML therapy, selectively inducing apoptosis in malignant myeloid cells while preserving normal hematopoiesis. This approach addresses major limitations of current treatments. Clinical trials are planned for relapsed/refractory AML, including TP53-mutant and drug-resistant cases.", "source_company": "Purdue University", "source_org_type": "大学", "row_number": 989, "target_meta": "CD33,DR5", "MOA_meta": "双特异性抗体"}, {"drug_name": "anti-human TFR1 antibodies", "company": "GenoBioTX LLC", "org_type": "公司", "target": "TFR1", "modality": "inhibitor", "importance_level": "中", "total_score": 61.5, "institution_score": 45, "track_score": 85, "milestone_score": 55, "field_heat_score": 80, "bonus_score": 0, "brief_reason": "药品为靶向TFR1的人源化抗体，用于脑递送shuttle技术，TFR1是脑穿梭热门靶点，赛道热度高；GenoBioTX为专注动物模型和CRO服务的中小型biotech，非头部药企，开发处于工具模型验证+抗体PK初步展示阶段，无临床里程碑。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6781", "id": "YlXM_5wBX1NQZOEH-LG5", "source_drug_name": "anti-human TFR1 antibodies", "title": "Humanized TFR1 knock-in mice: A powerful platform for evaluating TFR1-targeting brain shuttles", "abstract_text": "Background: The development of therapeutic antibodies and antibody-based diagnostics for the neurological disorders and gliomas is largely hampered by the presence of blood-brain barrier (BBB). While the BBB restricts most large molecules, it permits the transport of essential nutrients through selective transport mechanisms, creating opportunities to delivery drugs into the central nervous system using brain shuttle technologies. Transferrin receptor 1 (TFR1), which is expressed on brain endothelial cells (BECs), is one of the most extensively studied targets for receptor-mediated transcytosis (RMT) and has been validated as a gateway for brain drug delivery. To support the development of TFR1-targeting antibody or peptide-based brain shuttles, we generated a humanized TFR1 knock-in mouse model (hTFR1), serving as a robust preclinical platform for evaluating the efficacy, safety, and PK/PD profiles of TFR1-targeted therapeutics.\nMethods: The hTFR1 knock-in mouse model was generated by inserting the full-length human TFR1 coding sequence plus WPRE/polyA stop cassette into mouse Cd71 gene locus in C57BL/6 background via ES cell-based gene targeting, in which full-length human TFR1 proteins are expressed on the surface of targeted cells. To characterize the human TFR1 expression in the hTFR1 knockin mice, we assessed its localization on the brain endothelial cells by immunofluorescence (IF) staining and performed flow cytometry analysis to characterize its expression on activated T cells. Finally, we administered Trontinemab and the anti-human TFR1 antibodies generated via our SmocMab platform to hTFR1 mice through i.v. injection to evaluate th PK characteristics and brain uptake capability across the BBB.\nResults: Human TFR1 expression in hTFR1 mice was confirmed in brain microvessels and was upregulated on activated T lymphocytes. For PK analysis, brain tissues and serum samples were collected 24 hours after a single intravenous dose (10 mg/kg) of the human-specific TFR1 antibodies or a control antibody. Antibody concentrations were quantified by ELISA. The human-specific TFR1-binding antibody showed accelerated serum clearance and increased brain uptake compared with the control antibody, demonstrating its enhanced ability to penetrate the BBB.\nConclusions: Our humanized TFR1 knockin mice provides a powerful tool for preclinical evaluation of TFR1-targeting therapeutic antibodies.", "source_company": "GenoBioTX LLC", "source_org_type": "公司", "row_number": 12, "target_meta": "TFRC", "MOA_meta": "抑制剂"}, {"drug_name": "ASTU-045", "company": "NOVALIX", "org_type": "公司", "target": "METTL3", "modality": "inhibitor", "importance_level": "中", "total_score": 61.5, "institution_score": 45, "track_score": 85, "milestone_score": 55, "field_heat_score": 75, "bonus_score": 3, "brief_reason": "ASTU-045为新型选择性METTL3抑制剂，小分子口服，在MC38同系模型中单药肿瘤静止、联用anti-PD1显著肿瘤消退，体现免疫激活和重塑TME机制。NOVALIX为CRO而非头部药企，preclinical阶段强度中等，但METTL3作为新兴RNA调控热门靶点赛道热度高，领域潜力大。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8651", "id": "LVXM_5wBX1NQZOEH-LK6", "source_drug_name": "ASTU-045", "title": "ASTU-045, a novel METTL3 inhibitor with anti-tumor activity in the MC38 syngeneic mouse model", "abstract_text": "N6-methyladenosine (m6A) is the most prevalent modification of eukaryotic mRNA and plays a crucial role in gene regulation. Methyltransferase-like 3 (METTL3), the key catalytic component of the m6A methyltransferase complex, is primarily responsible for depositing m6A on target RNA. METTL3 is highly expressed in various cancers and is closely associated with tumor development. Previous studies have also shown that METTL3 inhibition activates anti-tumor immunity and reshapes the tumor microenvironment. Using structure-based drug design owing to the generation of multiple high resolution crystal structures of ligands bound to the METTL3-METTL14 complex, we developed novel METTL3 inhibitors. This effort led to the identification of ASTU-045, a selective METTL3 inhibitor that demonstrated cellular target engagement (m6A inhibition) and, in an in vitro co-culture system, showed strong, concentration dependent enhancement of PBMC-mediated killing of cancer cells. In the MC38 colorectal syngeneic model, oral administration of ASTU-045 to immune-competent, tumor-bearing mice resulted in tumor stasis. Combination treatment with ASTU-045 and an anti-PD1 antibody produced significant tumor regression. Strong target engagement was also observed in the spleen under both treatment conditions. In summary, we identified ASTU-045 as a novel, selective METTL3 inhibitor with high efficacy in the MC38 syngeneic model.", "source_company": "NOVALIX", "source_org_type": "公司", "row_number": 211, "target_meta": "METTL3", "MOA_meta": "抑制剂"}, {"drug_name": "HC031 ADC", "company": "Hongcheng Biopharma", "org_type": "公司", "target": "ADAM9", "modality": "ADC", "importance_level": "中", "total_score": 61.5, "institution_score": 45, "track_score": 75, "milestone_score": 75, "field_heat_score": 70, "bonus_score": 4, "brief_reason": "HC031 ADC靶向ADAM9（实体瘤过表达的金属蛋白酶），采用新型喜树碱类毒素payload和稳定linker，展示出强效抗瘤活性及NHP中极高MTD（120mg/kg）和优异安全性。机构为国内中小型biopharma（非头部），但ADC+新兴靶点赛道热度较高，前临床数据突出稳定性与宽治疗窗获加分，总分处于中等水平。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9642", "id": "glXM_5wBX1NQZOEH-LS6", "source_drug_name": "HC031 ADC", "title": "A novel ADAM9 ADC with robust anti-tumor efficacy and remarkable preclinical safety profile", "abstract_text": "ADAM9 (A Disintegrin And Metalloproteinase 9) is a transmembrane metalloproteinase overexpressed in a wide range of solid tumors, where it promotes tumor progression, metastasis, and poor prognosis. Internal immunohistochemistry analysis confirmed ADAM9 expressed at very low levels in most normal tissues, significant ADAM9 upregulation in tumor tissues, makes it a highly attractive and viable target for antibody-drug conjugate (ADC) development. An affinity optimized, humanized monoclonal antibody (HC031) was generated against human ADAM9. HC031 cross reacts with cyno ADAM9 with similar affinity. HC031 exhibited specific binding to human ADAM9 with no detectable binding to other ADAM family isoforms. HC031 selectively binds to membrane form of ADAM9 but not to short soluble ADAM9 predicting a regular pharmacokinetic profile unimpeded by soluble ADAM9. Furthermore, HC031 binding is partially dependent of bivalent cation, which may contribute to an improved safety profile. HC031 ADC was generated through conjugation with a novel, proprietary cytotoxic payload (camptothecin derivatives) via a highly stable linker. The resulting ADC demonstrated potent, target-specific cell killing in vitro and induced robust and sustained tumor regression in multiple xenograft models. Exploratory toxicology studies in non-human primates revealed an exceptionally maximum tolerated dose (MTD) of 120 mg/kg. No drug-related severe adverse events or significant abnormalities in hematological, biochemical, or coagulation parameters were observed. HC031 ADC exhibited favorable and dose-proportional PK profiles, with extended exposure of the intact ADC. Critically, the linker-payload demonstrated superior plasma stability.HC031 ADC drives potent anti-tumor activity in vitro and in vivo. Its exceptional stability in circulation and remarkable preclinical safety profile in NHPs predicts a significantly broader therapeutic window compared to existing ADAM9 ADCs.", "source_company": "Hongcheng Biopharma", "source_org_type": "公司", "row_number": 256, "target_meta": "ADAM9", "MOA_meta": "抗体偶联药物"}, {"drug_name": "SNX7886", "company": "University of South Carolina", "org_type": "大学", "target": "CDK8/CDK19", "modality": "PROTAC", "importance_level": "中", "total_score": 61.5, "institution_score": 30, "track_score": 90, "milestone_score": 70, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "SNX7886为基于BI1347的CDK8/CDK19双靶点PROTAC降解剂，在AML细胞系中显示优于kinase inhibitor的持续抗肿瘤活性并克服耐药。大学机构分数较低，但PROTAC热门赛道、CDK8/19在白血病中的潜力及preclinical强效数据（DC50 10 nM、完全生长抑制）支撑中高综合价值。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8727", "id": "XVXM_5wBX1NQZOEH-LG5", "source_drug_name": "SNX7886", "title": "Discovery of potent CDK8/CDK19 PROTAC degraders with superior anti-leukemia efficacy", "abstract_text": "Aggressive leukemias, including acute myeloid leukemia (AML), remain highly challenging diseases due to the lack of curative therapies. AML rapidly develops resistance to both conventional and targeted treatments, underscoring the urgent need for more effective therapeutic strategies. Recently, the transcription-regulating Mediator kinases CDK8 and CDK19 have emerged as promising targets, with CDK8/19 kinase inhibitors (CDK8/19i) now in clinical trials for leukemia. However, preliminary data from our laboratory demonstrate that leukemia cell lines exhibit heterogeneous and often incomplete responses to CDK8/19i, with many developing resistance after initial sensitivity. To test the hypothesis that direct depletion of CDK8/19 proteins in contrast to inhibiting kinase activity alone, may elicit more potent and durable anti-leukemia activity, we developed three series of PROteolysis TArgeting Chimeras (PROTACs) based on selective CDK8/19 inhibitors conjugated through diverse linkers to cereblon (CRBN)-recruiting ligands. After extensive optimization of both the kinase targeted warhead and composition of the linker, the most potent degrader obtained, SNX7886, induced efficient and simultaneous degradation of CDK8 and CDK19 across multiple cell types with a DC50 of 10 nM. When evaluated side-by-side with its cognate CDK8/19i (BI1347), SNX7886 consistently produced superior and sustained growth inhibition without the adaptive resistance observed with CDK8/19 kinase inhibitors in multiple leukemia lines. Notably, in an aggressive refractory AML cell line NOMO1, prolonged treatment with CDK8/19-PROTACs resulted in complete growth arrest, with no surviving cells detectable over extended exposure. Transcriptomic and proteomic analyses further revealed that CDK8/19-PROTACs engage both shared and distinct molecular pathways compared to CDK8/19i, indicating deeper disruption of transcriptional reprogramming circuits associated with AML survival and adaptation. These findings highlight targeted CDK8/19 degradation as a promising therapeutic strategy capable of overcoming key limitations of CDK8/19 kinase inhibitors in AML.", "source_company": "University of South Carolina", "source_org_type": "大学", "row_number": 377, "target_meta": "CDK8,CDK19", "MOA_meta": "PROTAC"}, {"drug_name": "GPC2.B7-H3 bicistronic CAR T cells", "company": "Children's Hospital of Philadelphia", "org_type": "医院", "target": "GPC2 & B7-H3", "modality": "CAR", "importance_level": "中", "total_score": 61.5, "institution_score": 35, "track_score": 85, "milestone_score": 80, "field_heat_score": 75, "bonus_score": 4, "brief_reason": "双靶点GPC2和B7-H3的bicistronic CAR T在高危神经母细胞瘤和髓母细胞瘤前临床模型中显示显著持久疗效和治愈率，优于单靶点CAR。机构为医院/学术型，得分较低，但热门CAR赛道+强前临床数据（包括长持久性和再挑战保护）支撑中高潜力。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1819", "id": "rVXM_5wBX1NQZOEH-LK6", "source_drug_name": "GPC2.B7-H3 bicistronic CAR T cells", "title": "Co-targeting GPC2 and B7-H3 with CAR T cells achieves durable responses in preclinical high-risk neuroblastoma and medulloblastoma models", "abstract_text": "Glypican 2 (GPC2) is highly expressed in pediatric cancers including high-risk neuroblastomas and medulloblastomas, and GPC2 CAR T cells are now in phase 1 trials (NCT05650749, NCT07087002). However, durable responses are limited by heterogeneous antigen expression, treatment-induced antigen loss, and poor CAR T persistence. In neuroblastoma, interconvertible adrenergic (ADRN) and mesenchymal (MES) states further complicate targeting, as state switching downregulates GPC2 and GD2, whereas B7-H3 remains consistently expressed. B7-H3 is also abundant across other GPC2⁺ cancers, supporting a dual GPC2.B7-H3 CAR strategy. To approach GPC2.B7-H3 dual CAR T cell targeting, we engineered seven GPC2/B7-H3 co-targeting bicistronic CAR constructs containing CD28, 4-1BB, or OX40 costimulatory domains and either two (dual, d1-3) or one (parallel, p1-4) CD3-ζ signaling domain. Among these, d1 and p2 were prioritized because they drove strong activation of Jurkat NFAT-GFP CAR T cells in co-cultures with isogenic NALM-6 cells expressing either or both antigens and showed superior cytokine secretion in human CAR T co-incubation assays compared with single-antigen B7-H3 (B) or GPC2 (G) CARs. In vivo, dual-targeting CAR T cells - double-transduced (B/G) or expressing d1 or p2 - achieved potent clearance of COG-N-453x neuroblastoma PDXs, with 16-week cure rates of 83.3%, 83.3%, and 100%, exceeding single CARs (B, 57.1%; G, 0%). Human CAR T cell persistence was detected in bone marrow and spleen of cured mice at 16 weeks, suggesting a role of enhanced T cell persistence in durable remissions. In the aggressive COG-N-561x model, only bicistronic CARs d1 and p2 achieved durable 14-15-week cures (d1, 100%; p2, 71.4%), surpassing double-transduced (B/G, 33.3%), co-administered (B+G, 20%), or single CARs (B, 20%; G, 0%). Upon rechallenge, only d1 and p2 cohorts rejected tumors and remained tumor-free long-term (d1, 71.4%; p2, 60%), again with persistent CAR T cells in bone marrow and spleen through the 36-week study endpoint. Finally, across in vitro medulloblastoma models, repeat tumor-stimulation assays confirmed superior activity of d1 and p2. In an aggressive orthotopic group 3 medulloblastoma 7316-10374 xenograft model where 100% of GPC2 CAR-treated mice relapsed, the p2 CAR outperformed d1 and the single B7-H3 CAR, with 16-week cure rates of 100%, 71.4%, and 60%, respectively, confirming the superiority of dual GPC2.B7-H3 targeting and a potential advantage of parallel CD3ζ-sharing designs. Altogether, GPC2.B7-H3 bicistronic CARs induced durable and curative responses across neuroblastoma and medulloblastoma models, nominating this approach as a next-generation GPC2 CAR T strategy for clinical testing.", "source_company": "Children's Hospital of Philadelphia", "source_org_type": "医院", "row_number": 599, "target_meta": "GPC2,CD276", "MOA_meta": "其他"}, {"drug_name": "fully human monoclonal antibodies to PTGFRN", "company": "A&G Pharmaceutical, Inc.", "org_type": "公司", "target": "PTGFRN", "modality": "ADC", "importance_level": "中", "total_score": 61.5, "institution_score": 45, "track_score": 85, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "靶点PTGFRN为新型内吞细胞表面蛋白，在头颈癌、肺癌、胰腺癌、髓母细胞瘤和间皮瘤等未满足需求癌症中过表达，正常组织低/无表达；药物为全人源mAb开发的ADC，体外nM级抑制增殖并体内有效抑制肿瘤生长，但机构为小型私人生物技术公司，项目仍处preclinical阶段。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5445", "id": "1FXM_5wBX1NQZOEH-LK6", "source_drug_name": "fully human monoclonal antibodies to PTGFRN", "title": "Fully human monoclonal antibodies for antibody drug conjugate development to a cell surface target expressed in cancers with unmet needs", "abstract_text": "The development of Antibody drug conjugates (ADCs) has shown to provide a powerful approach for the development of targeted therapies in Oncology. The majority of approved ADCs are focused on a few targets using a limited number of antibodies conjugated to a large array of liners and payloads combinations. However, in spite of the availability of these approved ADCs, there are several cancer types with poor prognosis for which the availability of targeted therapies remains limited. Addressing this limitation would require the identification of cell surface targets overexpressed in these cancers, the determination whether these targets are internalized, thus enabling the development of internalizing monoclonal antibodies able to deliver cytotoxic payload within the cancer cells. We have recently identified by proteomics approach such a target named PTGFRN as an internalizing, cell surface protein overexpressed in several cancers in need of targeted therapies such as head and neck, lung, pancreatic cancers, medulloblastoma and mesothelioma. We have demonstrated that PTGFRN expression was associated with migration, proliferation and spheroid formation, key steps in the metastasis process making PTGFRN a target of interest for the development of novel anti-cancer therapy. PTGFRN expression was overexpressed in mesothelioma, head and neck and medulloblastoma while it remained negative in corresponding normal tissues. Using humanized transgenic mice, we have developed and characterized fully human monoclonal antibodies to PTGFRN. Several screening assays were used to select high affinity, internalizing fully human monoclonal antibodies. ADCs derived from these antibodies were efficacious in a dose dependent fashion at the nM range to inhibit proliferation in vitro and tumor formation in vivo. for several PTGFRN expressing human cancer cell lines while it had no effect on PTGFRN negative human cell line. These in vitro and in vivo data will be presented here. These results establish PTGFRN as a target for antibody-drug conjugate development for cancers with unmet needs.", "source_company": "A&G Pharmaceutical, Inc.", "source_org_type": "公司", "row_number": 625, "target_meta": "PTGFRN", "MOA_meta": "抗体偶联药物"}, {"drug_name": "YX226", "company": "UHN Princess Margaret Cancer Centre", "org_type": "医院", "target": "HDAC3/8", "modality": "PROTAC", "importance_level": "中", "total_score": 61.5, "institution_score": 35, "track_score": 85, "milestone_score": 75, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "YX226为第二代双HDAC3/8 PROTAC降解剂，在DLBCL模型中显示体内抗肿瘤及免疫调节活性，PROTAC+HDAC靶点组合具有较高赛道热度。机构为医院研究型，开发阶段属较强preclinical但非头部公司导致总分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8708", "id": "7FXM_5wBX1NQZOEH-LK6", "source_drug_name": "YX226", "title": "Dual HDAC3/8 PROTAC degraders exert anti-tumor and immunomodulating effects in diffuse large B-cell lymphoma", "abstract_text": "Critical challenges remain in the clinical management of diffuse large B-cell lymphoma (DLBCL), as up to 40% of patients experience disease relapse or refractoriness. Despite the use of novel therapies, relapsed/refractory DLBCL results in a high risk of mortality, especially in the activated B-cell-like (ABC) subtype. Developing new therapeutic options for those patients becomes a pressing and clinically unmet need. Here, we explore the combined targeting of histone deacetylase (HDAC) 3 and 8 by targeted protein degradation to combat epigenetic deregulation in DLBCL. Through a comprehensive screen using single or dual HDAC3/8-targeting compounds in 12 DLBCL cell lines, we discovered that a highly selective, potent, first-in-class dual HDAC3/8 proteolysis-targeting chimera (PROTAC) degrader YX968 potently suppressed cell survival and proliferation. This effect was particularly more prominent and significantly stronger than single HDAC3 or 8 PROTACs in the ABC-DLBCL cell lines. Further functional evaluations revealed that YX968 specifically induced caspase-3-mediated apoptosis and caused cell cycle arrest. Mechanistically, YX968 profoundly upregulated H3K27 acetylation (H3K27ac), a key epigenetic mark for enhancer regulation, and generated a unique transcriptomic profile with downregulated genes associated with cell cycle regulation and upregulated genes implicated in immune activation. Moreover, we validated the gene expression results using flow cytometry for upregulated surface protein expression of the antigen presentation markers MHC-I and II, and detected enhanced CD8+ T-cell-induced cytotoxicity by YX968 in an in vitro T-cell co-culture assay, indicating its immunomodulating activities to potentiate anti-tumor immunity. Although YX968 showed in vitro efficacy, we found that it had poor metabolic stability, which precluded its potential in vivo application. To enhance the translation value of our approach, we developed a second-generation dual HDAC3/8 PROTAC (YX226) with improved metabolic stability while maintaining potent degradation, cell-killing, and immunomodulating activities. Using global proteomics, we confirmed the on-target activity of YX226 to selectively degrade HDAC3 and 8 but not the other HDAC isoforms. Importantly, we observed significant in vivo HDAC3/8 protein degradation and tumor growth inhibition by YX226 in a xenograft lymphoma model without adverse reduction of body weight, providing proof-of-principle evidence for in vivo efficacy and safety of a dual HDAC3/8 PROTAC. In conclusion, our findings demonstrate that dual HDAC3/8 PROTAC degraders induce significant anti-tumor and immunomodulating effects in our preclinical DLBCL models, supporting further development and evaluation of our second-generation bioavailable compound YX226 as a novel treatment option for DLBCL.", "source_company": "UHN Princess Margaret Cancer Centre", "source_org_type": "医院", "row_number": 640, "target_meta": "HDAC3,HDAC8", "MOA_meta": "PROTAC"}, {"drug_name": "DNA damage chemical inducers of proximity (DD-CIP)", "company": "Stanford University", "org_type": "大学", "target": "PARP1/2 和 BRD4", "modality": "other", "importance_level": "中", "total_score": 61.5, "institution_score": 45, "track_score": 85, "milestone_score": 60, "field_heat_score": 75, "bonus_score": 5, "brief_reason": "DD-CIP通过化学诱导PARP1/2与BRD4的邻近来重编程PARPi作用机制，诱导DNA损伤和肿瘤细胞凋亡，属于创新的化学生物学方法。斯坦福大学preclinical数据较扎实但非产业机构，赛道新颖热门但早期阶段导致综合评分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11299", "id": "Wp7ECZ0BZznHJdntvNYd", "source_drug_name": "DNA damage chemical inducers of proximity (DD-CIP)", "title": "DNA damage chemical inducers of proximity (DD-CIP) for targeted cancer therapy", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Stanford University", "source_org_type": "大学", "row_number": 675, "target_meta": "PARP1,PARP2,BRD4", "MOA_meta": "其他"}, {"drug_name": "TOPO1 inhibitor", "company": "ICE Bioscience", "org_type": "公司", "target": "未披露", "modality": "ADC", "importance_level": "中", "total_score": 61.5, "institution_score": 45, "track_score": 85, "milestone_score": 55, "field_heat_score": 75, "bonus_score": 3, "brief_reason": "该工作聚焦TOPO1抑制剂为基础的双负载ADC组合，旨在通过DDR和细胞周期机制克服ADC耐药，靶点未具体披露但属于热门ADC赛道；ICE Bioscience作为国内专注早期药物发现的CRO公司，非头部药企，preclinical框架和筛选有一定方法学价值但无明确临床里程碑。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5022", "id": "2VXM_5wBX1NQZOEH-LO6", "source_drug_name": "TOPO1 inhibitor", "title": "Identification of synergistic dual payload combinations for antibody-drug conjugates to overcome resistance through resistance modeling", "abstract_text": "Background: Antibody-Drug Conjugates (ADCs) are potent cancer therapeutics, but resistance to ADCs or their single payloads remains a critical clinical barrier. Dual payload ADCs—co-delivering two distinct payloads via a single antibody—offer a promising solution by leveraging complementary mechanisms. Clinical progress and pipeline candidates validate this approach. However, a systematic framework to identify resistance-tailored synergistic payload combinations and decipher their mechanisms is underdeveloped.\nMethods: We established 10+ drug-resistant cell lines against clinical ADCs/payloads via long-term selection. To elucidate resistance mechanisms and predict synergistic combinations, we performed RNA-seq and WES on resistant/parental pairs, followed by pathway enrichment and synthetic lethality prediction. We screened 100+ dual payload combinations (resistant/parental cell panel, viability assay) to identify hits. Mechanisms of hit combinations were investigated via bioinformatics analysis and validated by Western blotting/immunofluorescence (DDR markers and cell cycle markers).\nResults: bioinformatics analysis identified key resistance mechanisms including elevated P-gp transporter and reduced antigen expression. We screened 100+ combinations (TOPO1 inhibitors paired with DDR inhibitors, CDK inhibitors, TYR kinase inhibitors, toxins) and identified three synergistic hits including TOPO1 inhibitor combined with DDR related targets and cell cycle targets. All hits showed significant synergistic effect (IC50 shifts >3 folds and CI<0.9) in resistant cells, while single payloads had minimal efficacy. Bioinformatics implicated enhanced DNA damage and cell cycle dysregulation as core mechanisms, validated by pathway assays.\nConclusions: Our study establishes a systematic framework (resistance modeling, bioinformatics, high-throughput screening) to identify synergistic dual payload combinations for ADCs. The three TOPO1-based hit combinations potently overcome resistance via validated DDR/cell cycle mechanisms. This work provides a rational basis for next-generation dual-payload ADC development and a generalizable strategy to accelerate resistance-overcoming regimen discovery across cancer therapies", "source_company": "ICE Bioscience", "source_org_type": "公司", "row_number": 802, "target_meta": "not available", "MOA_meta": "抗体偶联药物"}, {"drug_name": "oncolytic herpes simplex virus", "company": "The Abigail Wexner Research Institute at Nationwide Children’s Hospital", "org_type": "研究机构", "target": "未披露", "modality": "other", "importance_level": "中", "total_score": 61.5, "institution_score": 55, "track_score": 75, "milestone_score": 60, "field_heat_score": 70, "bonus_score": 2, "brief_reason": "溶瘤单纯疱疹病毒（oHSV）通过选择性裂解肿瘤细胞并刺激抗肿瘤免疫反应发挥双重作用，靶点未明确披露。机构为知名儿童医院研究机构非头部药企但有病毒疗法积累，赛道为热门溶瘤病毒领域且GBM未满足需求高，处于早期临床IA期并显示免疫重塑潜力，总分中等重要性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9551", "id": "71XM_5wBX1NQZOEH-LO6", "source_drug_name": "oncolytic herpes simplex virus", "title": "Spatial profiling of the tumor immune microenvironment following oncolytic herpes simplex virus treatment in glioblastoma", "abstract_text": "Glioblastoma (GBM) is the most common and aggressive malignant brain tumor in adults, with an extremely low 5-year survival rate of ~5%. Despite established surgery and chemoradiotherapy treatments, outcomes remain poor due to GBM’s profound heterogeneity and highly immunosuppressive tumor immune microenvironment (TIME). Emerging immunotherapies offer new opportunities to overcome these barriers. Among them, oncolytic herpes simplex viruses (oHSVs) stand out for their dual ability to selectively lyse tumor cells while stimulating robust anti-tumor immune responses. Preclinical and early clinical studies demonstrate that oHSVs can profoundly remodel immune cell expression within tumors, but these analyses lack spatial insight. Spatial multi-omics technologies now enable precise mapping of such immune transcriptome and proteome changes, answering how immune reorganization shapes the GBM TIME. The present study utilized 10x Genomics Visium spatial multi-omics to comprehensively map oHSV-induced immune responses in human GBM and explore their association with patient outcomes. Brain tumor samples were obtained from a Phase IA dose-escalation oHSV trial for recurrent glioma, with tissue collected both before treatment and at post-treatment resection. Across four patients, a total of seventeen formalin-fixed, paraffin-embedded samples were profiled using the Visium Spatial Gene Expression (Whole Transcriptome) and Visium Immune Profiling (Protein) panels. Spatial multi-omic data were analyzed in Seurat, leveraging a human brain immune reference integrated with our oHSV single-cell RNA-sequencing data to enhance cell type identification for spatial deconvolution. We characterized key immune cell populations, evaluating how their localization, abundance, and expression varied across treatment status (pre- vs. post-oHSV), spatial context (tumor bed vs. periphery), and clinical response (responders vs. non-responders). We also explored the use of custom viral RNA probes to detect viral presence within tissue; while signal detection was limited, these efforts informed future optimization of viral localization methods. By comparing spatial immune architectures between responders and non-responders, we identified trends that illuminate how immune cell organization shapes therapeutic efficacy. Furthermore, the observed concordance between spatial gene and protein expression of key immune markers reinforces the biological validity of these signatures and suggests their possible association with treatment response. Ultimately, elucidating the mechanisms by which oHSV modulates the GBM TIME advances our understanding of its anti-tumor effect and provides a rationale for its continued clinical development.", "source_company": "The Abigail Wexner Research Institute at Nationwide Children’s Hospital\nThe Steve and Cindy Rasmussen Institute for Genomic Medicine, The Abigail Wexner Research Institute at Nationwide Children’s Hospital", "source_org_type": "研究机构\n医院", "row_number": 820, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "mesothelin-targeted CAR T-cell therapy", "company": "Memorial Sloan Kettering Cancer Center", "org_type": "医院", "target": "mesothelin", "modality": "CAR", "importance_level": "中", "total_score": 61.5, "institution_score": 45, "track_score": 85, "milestone_score": 60, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "靶点为mesothelin的CAR-T细胞疗法，采用腹腔给药针对食管胃交界癌伴腹膜癌病。机构为顶级癌症中心但非药企导致机构分不高，赛道为热门细胞治疗且区域给药有创新，处于I期临床初步开发阶段。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/12012", "id": "dVXM_5wBX1NQZOEH-LS6", "source_drug_name": "mesothelin-targeted CAR T-cell therapy", "title": "A phase I trial of intraperitoneal (IP) mesothelin (MSLN)-targeted CAR T-cell therapy in patients with MSLN-positive esophagogastric cancer (EGC) with peritoneal carcinomatosis", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Memorial Sloan Kettering Cancer Center", "source_org_type": "医院", "row_number": 914, "target_meta": "MSLN", "MOA_meta": "其他"}, {"drug_name": "anti-PD-1 antibody-drug conjugate", "company": "Technion-Israel Institute of Technology", "org_type": "大学", "target": "BMP1 (CD8⁺ T cell-derived)", "modality": "ADC", "importance_level": "中", "total_score": 61.5, "institution_score": 35, "track_score": 85, "milestone_score": 75, "field_heat_score": 80, "bonus_score": 6, "brief_reason": "该ADC将anti-PD-1抗体与BMP1抑制剂偶联，双机制阻断PD-1并特异抑制CD8⁺ T细胞来源的BMP1以逆转治疗诱导的ECM重塑、克服免疫治疗耐药。大学机构得分较低，但ADC+免疫+基质调控新机制组合在热门赛道中具创新性且preclinical显示显著增效。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/361", "id": "iFXM_5wBX1NQZOEH-LS6", "source_drug_name": "anti-PD-1 antibody-drug conjugate", "title": "Immune checkpoint blockade induces extracellular remodeling through cytotoxic T cells expressing BMP1", "abstract_text": "The extracellular matrix (ECM) constitutes a dynamic, acellular scaffold within tumors that provides structural and biochemical cues regulating cancer cell proliferation, invasion, immune exclusion, and metastatic dissemination. While traditionally the ECM is viewed as a stromal product of fibroblasts and other mesenchymal cells, emerging evidence suggests that anti-cancer therapies themselves can profoundly reshape it. We and others have previously demonstrated that certain systemic therapies including chemotherapy induce pulmonary ECM remodeling that promotes metastatic spread. Here, we investigated whether immune checkpoint inhibitors (ICIs), specifically anti-PD-1 therapy, similarly affect tumor ECM composition and architecture, and how this remodeling impacts immunotherapy response. Transcriptomic analysis of breast cancer patient samples before and after ICI treatment revealed significant enrichment of ECM-associated gene signatures following therapy. In multiple murine tumor models, anti-PD-1 treatment induced pronounced ECM remodeling characterized by de novo collagen and elastin deposition, increased matrix crosslinking, and upregulation of ECM-modifying enzymes. Unexpectedly, we identified bone morphogenetic protein 1 (BMP1), a metalloprotease that activates lysyl oxidase (LOX), collagen maturation, and TGF-β signaling, as highly expressed and secreted by CD8⁺ cytotoxic T cells upon ICI stimulation. Mechanistically, CD8⁺ T cell-derived BMP1 was essential for therapy-induced ECM remodeling, and conditional inhibition of BMP1 specifically within CD8⁺ T cells reversed pathological matrix accumulation, reduced immune exclusion, and significantly enhanced anti-PD-1 efficacy across immunotherapy-resistant melanoma, breast, and lung cancer models. These findings redefine CD8⁺ T cells as active regulators of the structural tumor microenvironment rather than solely cytotoxic effectors. To therapeutically exploit this mechanism, we engineered a novel antibody-drug conjugate (ADC) platform in which a selective BMP1 enzymatic inhibitor is conjugated to an anti-PD-1 antibody backbone. This dual-mechanism construct enables checkpoint blockade while simultaneously restricting BMP1 activity within activated CD8⁺ T cells, thereby preventing therapy-induced ECM remodeling. Treatment with this ADC sensitized otherwise resistant tumors to immunotherapy and improved tumor control compared with conventional anti-PD-1 therapy. Collectively, our findings uncover a previously unrecognized immune-mediated pathway driving ECM remodeling during immunotherapy and establish selective targeting of CD8⁺ T cell-derived BMP1 as a rational strategy to overcome resistance to immunotherapy. This study provides a conceptual and translational framework for integrating tumor immunology with matrix biology to improve clinical responses in solid tumors.", "source_company": "Technion-Israel Institute of Technology", "source_org_type": "大学", "row_number": 928, "target_meta": "BMP1", "MOA_meta": "抗体偶联药物"}, {"drug_name": "TROP2 CAR engineered IL-15-transduced cord blood-derived NK cells", "company": "UT Texas MD Anderson Cancer Center", "org_type": "医院", "target": "TROP2", "modality": "CAR", "importance_level": "中", "total_score": 61.5, "institution_score": 45, "track_score": 85, "milestone_score": 60, "field_heat_score": 75, "bonus_score": 3, "brief_reason": "靶点TROP2的CAR-NK细胞疗法（IL-15增强），属于热门细胞治疗赛道且靶点在实体瘤有较高关注度。由MD Anderson医院开展的I期研究，preclinical基础较好但机构非商业公司导致总分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/12224", "id": "Rp7M_5wBZznHJdnt_W3O", "source_drug_name": "TROP2 CAR engineered IL-15-transduced cord blood-derived NK cells", "title": "Phase I study of TROP2 CAR engineered IL-15-transduced cord blood-derived NK cells in advanced solid tumors (TROPIKANA)", "abstract_text": "Abstract is embargoed at this time.", "source_company": "UT Texas MD Anderson Cancer Center", "source_org_type": "医院", "row_number": 997, "target_meta": "TROP2", "MOA_meta": "其他"}, {"drug_name": "MTA-cooperative PRMT5/MEP50 degraders", "company": "Icahn School of Medicine at Mount Sinai", "org_type": "大学", "target": "PRMT5/MEP50", "modality": "degrader", "importance_level": "中", "total_score": 61.5, "institution_score": 35, "track_score": 85, "milestone_score": 70, "field_heat_score": 75, "bonus_score": 3, "brief_reason": "药物为MTA协同型PRMT5/MEP50降解剂，利用MTAP缺失合成致死实现MTAP-null肿瘤选择性杀伤，机制新颖且安全性提升。机构为大学得分偏低，但PROTAC类degrader赛道热度高、preclinical展示清晰选择性优势，综合潜力中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8715", "id": "yp7M_5wBZznHJdnt_W3O", "source_drug_name": "MTA-cooperative PRMT5/MEP50 degraders", "title": "Discovery and development of PRMT5/MEP50 degraders for the selective targeting of MTAP-null cancers", "abstract_text": "Protein arginine methyltransferase 5 (PRMT5) is an important regulator of various biological processes through the mono- and symmetric dimethylation of protein substrates. PRMT5 is overexpressed in multiple human cancers, and its overexpression is often associated with poor prognosis. We recently reported MS115, a best-in-class PRMT5 degrader that potently and selectively degraded PRMT5 and its coactivator, MEP50, in concentration-, time-, and ubiquitin-proteasome system-dependent manners. MS115 displayed markedly improved PRMT5/MEP50 degradation potency over published PRMT5 degraders, which translated to superior antiproliferative effect in both breast and prostate cancer cells. More importantly, MS115 exhibited safer cytotoxicity profile compared to existing PRMT5 degraders and inhibitors in normal cells. Nonetheless, residual antiproliferative activity in MTAP-proficient cells highlights the need for improved therapeutic selectivity. To address this limitation, we tackled the synthetic lethality between PRMT5 and MTAP loss. MTAP homozygous deletions, present in approximately 15% of human cancers, lead to accumulation of methylthioadenosine (MTA), an endogenous PRMT5 inhibitor. By leveraging MTA-cooperative PRMT5 inhibitors, we generated a series of PRMT5/MEP50 degraders that selectively degraded PRMT5 and MEP50 and suppressed proliferation in MTAP-null cancer cells, while sparing MTAP-wild-type counterparts across breast cancer and cholangiocarcinoma models. This targeted selectivity enables the study of both catalytic and non-catalytic functions of PRMT5 with substantially improved tolerability. Collectively, we have discovered MS115 and multiple MTA-cooperative PRMT5/MEP50 degraders with enhanced potency and safety, providing valuable chemical probes and promising candidates for the treatment of cancers driven by PRMT5 dysregulation.", "source_company": "Icahn School of Medicine at Mount Sinai", "source_org_type": "大学", "row_number": 1094, "target_meta": "PRMT5", "MOA_meta": "降解剂"}, {"drug_name": "NONO covalent modulators", "company": "Talus Bio", "org_type": "公司", "target": "NONO", "modality": "inhibitor", "importance_level": "中", "total_score": 61.5, "institution_score": 55, "track_score": 75, "milestone_score": 55, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "靶向NONO的共价小分子调节剂，通过破坏AR及AR-V7表达和功能，针对mCRPC这一难治阶段。Talus Bio为新兴biotech，平台创新但规模较小；赛道涉及转录因子靶向+共价抑制具一定新颖性，处于hit-to-lead优化至in vivo PoC阶段。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5690", "id": "0Z7M_5wBZznHJdnt_W3O", "source_drug_name": "NONO covalent modulators", "title": "Targeting NONO as a therapeutic strategy for metastatic castration-resistant prostate cancer (mCRPC)", "abstract_text": "Prostate cancer is among the most prevalent cancers among men, with approximately 300,000 new cases diagnosed annually. While androgen deprivation therapy (ADT) is effective in controlling early-stage prostate cancer, treatment options are limited once the disease advances to metastatic castration-resistant prostate cancer (mCRPC). This progression underscores the critical need for innovative therapeutic strategies to address this difficult-to-treat stage. Resistance to ADT arises when androgen receptor (AR) signaling becomes active even in the absence of ligands. This resistance is often driven by mutations in the ligand-binding domain (LBD) of AR or the expression of AR variants (AR-Vs) that lack the LBD. Uncovering new strategies to inhibit these constitutively active AR-Vs could provide significant clinical benefit for patients with mCRPC.\nTalus Bio has developed a groundbreaking technology, TF-Scan, the first cell-based global screening platform specifically designed to target transcription factors (TF) and other regulome proteins. TF-Scan integrates functional proteomics, automated cell processing, and machine learning to evaluate a drug’s ability to modulate the activity of DNA-bound proteins in live human cells. This is an ideal system to identify and optimize compounds that suppress AR through direct or indirect mechanisms.\nBuilding on this mechanistic insight, we applied TF-Scan to systematically identify covalent modulators of NONO (non-POU domain-containing octamer-binding protein) that disrupt AR expression and protein binding. We then initiated an iterative hit-to-lead optimization campaign leveraging TF-Scan to optimize NONO binding, AR disruption and proteome-wide selectivity.. Our chemical series engages NONO at C145 with high selectivity in intact prostate cancer cells and produces a consistent reduction in chromatin-bound AR. Lead compounds suppress both full-length AR and AR-V7 protein levels, downregulate multiple downstream AR/AR-V target genes, and achieve sub-micromolar EC50 values for blocking the accumulation of AR mRNA isoforms. These effects translate into concordant anti-proliferative activity in AR-dependent prostate cancer models. Several advanced analogs exhibit improved solubility, enhanced microsomal stability, and overall favorable ADME/PK profiles. Based on these results, we are advancing our most promising candidates into proof-of-concept in vivo efficacy studies to evaluate their potential as first-in-class NONO/AR-targeting therapeutics for mCRPC.", "source_company": "Talus Bio", "source_org_type": "公司", "row_number": 1100, "target_meta": "NONO", "MOA_meta": "抑制剂"}, {"drug_name": "novel hydrophilic linker", "company": "Lotte Biologics", "org_type": "公司", "target": "未披露", "modality": "other", "importance_level": "中", "total_score": 61.5, "institution_score": 65, "track_score": 75, "milestone_score": 40, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "该项目聚焦新型亲水linker技术用于改善ADC的稳定性和体外活性，但摘要被禁未披露具体靶点或药物细节。Lotte Biologics作为韩国新兴生物制药公司在ADC平台有布局，亲水linker属于ADC热门优化方向，但仅preclinical技术改进阶段，整体里程碑价值有限。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11412", "id": "P57M_5wBZznHJdnt_W7O", "source_drug_name": "novel hydrophilic linker", "title": "Novel hydrophilic linker to improve stability and in vitro activity of antibody-drug conjugates", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Lotte Biologics", "source_org_type": "公司", "row_number": 1168, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "autologous dual-target BCMA/CD19 CAR T-cell therapy", "company": "VeGen Labs", "org_type": "公司", "target": "BCMA/CD19", "modality": "CAR", "importance_level": "中", "total_score": 61.5, "institution_score": 45, "track_score": 85, "milestone_score": 55, "field_heat_score": 80, "bonus_score": 2, "brief_reason": "双靶点BCMA/CD19 CAR-T针对复发/难治多发性骨髓瘤，靶点组合和CAR-T modality在该领域热度高。VeGen Labs为印度本土新兴公司，处于I/II期临床但摘要受限，综合潜力中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/12126", "id": "V57M_5wBZznHJdnt_W7P", "source_drug_name": "autologous dual-target BCMA/CD19 CAR T-cell therapy", "title": "First in India, phase 1/2 study of an indigenously adapted, cost-efficient autologous dual-target BCMA/CD19 CAR T-cell therapy for relapsed or refractory multiple myeloma", "abstract_text": "Abstract is embargoed at this time.", "source_company": "VeGen Labs", "source_org_type": "公司", "row_number": 1184, "target_meta": "BCMA,CD19", "MOA_meta": "其他"}, {"drug_name": "CAR-T cell therapy", "company": "Bio LIMS INC", "org_type": "公司", "target": "未披露", "modality": "CAR", "importance_level": "中", "total_score": 61, "institution_score": 45, "track_score": 85, "milestone_score": 55, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "产品为针对CAR-T细胞疗法的多代理AI系统，用于自主靶点发现、毒性预测和分子设计，本身非具体药物而是开发平台工具。机构为小型IT/生物信息公司而非头部药企，得分较低，但CAR-T赛道热度高且AI赋能固瘤潜力大，整体中等重要性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/2491", "id": "41XM_5wBX1NQZOEH-LG6", "source_drug_name": "CAR-T cell therapy", "title": "Multi-agent AI system for autonomous CAR-T development: Integrated target discovery, toxicity prediction, and rational molecular design for cancer immunotherapy", "abstract_text": "Background: Chimeric antigen receptor T-cell (CAR-T) therapy has achieved remarkable success in hematologic malignancies, yet only 6 products have gained FDA approval since 2017, with target selection and toxicity remaining critical bottlenecks. Conventional pipelines require 8-12 years with 40-60% failure rates due to inadequate validation or safety liabilities. Notable clinical setbacks underscore urgent need for autonomous systems predicting safety risks before costly trials.\nMethods: We developed Bio AI Agent, a multi-agent AI system powered by large language models enabling autonomous CAR-T development. The architecture comprises six agents: (1) Target Selection for antigen prioritization, (2) Toxicity Prediction integrating tissue atlases and pharmacovigilance databases, (3) Molecular Design for modular CAR engineering, (4) Patent Intelligence for freedom-to-operate analysis, (5) Clinical Translation for regulatory guidance, and (6) Decision Orchestration for multi-agent coordination. Agents communicate through shared knowledge base with vector database and natural language interfaces.\nResults: Retrospective validation demonstrated autonomous capabilities across key stages. Target assessment streamlined 3-4 month workflows to rapid processing. Toxicity prediction accurately identified problematic targets through expression profiling and adverse event analysis. Patent intelligence flagged infringement risks enabling compliant design strategies. Molecular design demonstrated systematic optimization with real-time prediction. Decision orchestration generated comprehensive roadmaps spanning validation, pathway development, and clinical translation.\nConclusions: Bio AI Agent addresses critical CAR-T development gaps through intelligent collaboration across target discovery, safety prediction, and molecular optimization. Autonomous identification of liability targets with mitigation strategies demonstrates potential for reducing attrition and improving safety. Multi-agent architecture enables parallel processing and specialized reasoning superior to monolithic systems. As CAR-T expands into solid tumors, autonomous platforms will be essential for accelerated precision oncology.", "source_company": "Bio LIMS INC", "source_org_type": "公司", "row_number": 20, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "AOH analogues", "company": "Beckman Research Institute of The City of Hope", "org_type": "研究机构", "target": "caPCNA", "modality": "inhibitor", "importance_level": "中", "total_score": 61, "institution_score": 45, "track_score": 75, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "靶向癌相关酸性异构体caPCNA的小分子抑制剂，通过杂环替换优化AOH1996的溶解度、代谢稳定性和儿科口服液剂型潜力。研究机构背景导致机构分较低，但新型靶点+口服小分子+AML儿科方向+已有临床I期基础使赛道和里程碑具备一定吸引力。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6544", "id": "R57M_5wBZznHJdnt_W3O", "source_drug_name": "AOH analogues", "title": "Development of hydrophilic and metabolically stable heterocyclic AOH1996 analogues for pediatric AML oral liquid formulations", "abstract_text": "Proliferating cell nuclear antigen (PCNA) is a key regulator of at least 11 essential cellular processes, including DNA replication and repair, transcription, cell cycle progression, apoptosis induction, transcription-replication conflict resolution, energy metabolism, chromosome maintenance, mitosis, and immune surveillance. In tumor cells, PCNA exists as a cancer-associated acidic isoform (caPCNA), while non-malignant cells express only a basic isoform (nmPCNA). The absence of caPCNA in normal cells makes it an attractive target for selective cancer therapy. We previously developed AOH1996, a first-in-class small molecule that selectively inhibits caPCNA, inducing apoptosis in cancer cells without detectable toxicity in non-malignant cells. AOH1996 binds to caPCNA, stabilizes its trimeric structure, decreases chromatin association, and suppresses tumor cell proliferation. AOH1996 is orally bioavailable and is currently being evaluated in two first-in-human Phase I clinical trials: one for treatment refractory solid tumors (NCT05227326) and the other for acute myeloid leukemia (NCT06763341). No dose-limiting toxicities have been observed to date, with ongoing dose escalation currently reaching 1110 mg PO BID. In this study, we aimed to enhance the aqueous solubility and pharmacokinetic properties of AOH1996 through strategic single-point heteroatom substitutions. By replacing selected aromatic carbons with nitrogen atoms, we generated a series of quinoline, isoquinoline, and pyridine analogues optimized for liquid oral formulations that will be ultimately compatible with pediatric administration for AML. Structure-activity relationship (SAR) analyses across these three heterocyclic scaffolds identified several analogues with improved solubility, potency, selectivity, and metabolic stability when compared to the clinical lead. For example, introducing two nitrogen atoms into the aromatic regions of one analogue reduced the CLogP to 3.35 (vs. 4.46 for AOH1996) while maintaining IC₅₀ values comparable to the parent compound. This reduction in lipophilicity corresponds to an estimated ~13-fold increase in aqueous solubility, making this analogue more amenable to liquid formulation for oral administration. Over 30 novel AOH analogues were synthesized and evaluated for antiproliferative activity across eight tumor cell lines (including Molm-13, THP-1, HTB-0225, SK-N-AS, HCT116, U251, and MDA-MB-468), as well as in AML mouse models. Synthetic routes, biological data, and preliminary in vivo results will be presented. Together, these findings lay the groundwork for the next generation of AOH-based therapeutics with improved physicochemical and pharmacological properties suitable for pediatric oncology applications.", "source_company": "Beckman Research Institute of The City of Hope", "source_org_type": "研究机构", "row_number": 82, "target_meta": "PCNA", "MOA_meta": "抑制剂"}, {"drug_name": "SON-5010", "company": "Sonnet Biotherapeutics, Inc.", "org_type": "公司", "target": "HER2", "modality": "PDC", "importance_level": "中", "total_score": 61, "institution_score": 45, "track_score": 85, "milestone_score": 55, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "SON-5010为靶向HER2的peptide drug conjugate (PDC)，采用FHAB平台实现精确DAR控制和更好肿瘤穿透，与传统IgG ADC相比显示相似抗肿瘤活性且毒性低。公司为小型美国biotech，preclinical POC阶段但平台创新性强，ADC赛道及HER2靶点热度高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5613", "id": "uFXM_5wBX1NQZOEH-LG6", "source_drug_name": "SON-5010", "title": "SONNET 5010, a novel proprietary peptide drug conjugate lock and load platform", "abstract_text": "Background: Conventional IgG-based antibody-drug conjugates (ADCs) face major limitations, including heterogeneous drug-to-antibody ratios (DAR), variable pharmacokinetics, limited tumor penetration, and linker instability that can lead to off-target toxicity. To overcome these challenges, Sonnet has developed a non-IgG peptide drug conjugate (PDC) platform that enables precise drug loading and improved distribution. SON-5010 is the first proof-of-concept PDC generated using this approach and incorporates Sonnet’s FHAB® (Fully Human Albumin Binding) domain to enhance half-life, tumor accumulation, and overall pharmacokinetics.\nMethods: SON-5010 consists of a dual anti-HER2 single-chain variable fragment (scFv) targeting domain flanking the FHAB motif, combined with an 18-amino-acid Docking Peptide-Payload Domain (DPPD). The DPPD contains three lysine residues that enable deterministic DAR3 conjugation with MMAE. The scFv-FHAB-scFv targeting domain was expressed in CHO cells, while the MMAE-loaded DPPD was chemically synthesized. The components were linked through standard conjugation chemistry to generate an ~88 kDa PDC. In vitro assessments included serum stability at 37°C and cytotoxicity testing in HER2-high (SKBR3) and HER2-negative (A549) cells. In vivo antitumor activity was evaluated in the HER2-positive BT-474 breast carcinoma xenograft model. SON-5010 was designed for direct comparison with trastuzumab, which contains the same anti-HER2 domain and Lys linker chemistry as MMAE (DAR3), except that it is attached to the DPPD rather than an IgG.\nResults: SON-5010 demonstrated strong serum stability and potent cytotoxicity in HER2-expressing SKBR3 cells, with no activity in HER2-negative A549 cells. In vivo, SON-5010 produced tumor growth inhibition comparable to HER2-directed MMAE ADC control of trastuzumab. At 10 mg/kg, SON-5010 showed no detectable toxicity, with stable body weight and no adverse clinical signs. The smaller size of the PDC and the FHAB-mediated albumin binding likely contributed to improved tumor penetration and favorable tolerability.\nConclusions: SON-5010 demonstrates the potential of Sonnet’s modular PDC platform to address key limitations of IgG-based ADCs. The architecture enables full DAR control, enhanced penetration, and flexible engineering of targeting domains and payload chemistries. The platform also supports dual-payload and multispecific designs, offering opportunities to overcome resistance and improve therapeutic index. Early results indicate that SON-5010 is a promising next-generation targeted therapeutic candidate.", "source_company": "Sonnet Biotherapeutics, Inc.", "source_org_type": "公司", "row_number": 194, "target_meta": "HER2", "MOA_meta": "其他"}, {"drug_name": "TXN-A", "company": "Txinno Bioscience Inc.", "org_type": "公司", "target": "ULK1", "modality": "degrader", "importance_level": "中", "total_score": 61, "institution_score": 45, "track_score": 85, "milestone_score": 60, "field_heat_score": 70, "bonus_score": 5, "brief_reason": "TXN-A为口服生物可利用的ULK1降解剂，靶向自噬调控关键节点ULK1，具有first-in-class特性，主要用于TNBC治疗。机构为2020年成立的韩国小型biotech，得分一般；赛道为新兴degrader+ULK1（自噬靶点在肿瘤中有潜力），热度较高；摘要仍embargoed，处于Discovery阶段但AACR poster展示有一定里程碑价值。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11470", "id": "gVXM_5wBX1NQZOEH-LO6", "source_drug_name": "TXN-A", "title": "Discovery and characterization of TXN-A: A first-in-class, orally bioavailable ULK1 degrader with high selectivity and potency for TNBC treatment", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Txinno Bioscience Inc.", "source_org_type": "公司", "row_number": 243, "target_meta": "ULK1", "MOA_meta": "降解剂"}, {"drug_name": "bispecific PD-L1:CD3 T-cell engager", "company": "Seattle Children's Research Institute", "org_type": "研究机构", "target": "PD-L1", "modality": "bispecific antibody", "importance_level": "中", "total_score": 61, "institution_score": 35, "track_score": 85, "milestone_score": 75, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "靶向PD-L1的双特异性T细胞衔接器（TCE），在多种颅内原发和转移瘤的临床前模型中显示出显著抗肿瘤活性并实现部分肿瘤清除。机构为研究机构得分较低，但热门TCE赛道+脑瘤未满足需求+较强的preclinical疗效数据（含NHP安全性）使综合重要性达中等偏上水平。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4521", "id": "0FXM_5wBX1NQZOEH-LG6", "source_drug_name": "bispecific PD-L1:CD3 T-cell engager", "title": "A bispecific PDL1:CD3 T-cell engager potently kills intractable primary and metastatic intracranial tumors", "abstract_text": "Introduction: Central nervous system tumors represent a huge unmet medical need. Many pediatric and adult brain cancers and cancers (e.g., lung, colon, breast) with CNS involvement remain largely intractable despite standard of care and advanced treatment strategies. We engineered a bispecific PD-L1 targeted T-cell engager (TCE) and discovered promising efficacy in a wide range of pre-clinical intracranial tumor models, including some models with intact blood brain barriers.\nMethods: Anti-tumor activity of a systemically administered PD-L1:CD3 TCE was interrogated in 14 intracranially implanted tumor xenografts representing poor-prognosis pediatric brain tumors, adult glioblastoma, and metastatic lung, breast, and colorectal cancers. On-target/off-cancer toxicity was evaluated in mice transgenic for human PD1/PD-L1 or CD3ε with surrogate chimeric TCEs for species appropriate binding over 2- and 4-week treatment periods with repeated dosing. Dose range finding study in non-human primates was conducted to establish the safety profile of the lead TCE.\nResults: Median and overall survival were significantly extended by TCE treatment in 4 of 5 models of pediatric brain tumors (2 diffuse midline glioma, 1 medulloblastoma, 2 high-grade glioma), 2 of 3 models of adult glioblastoma, and all 6 models of intracranial metastases (3 lung adenocarcinoma, 2 triple-negative breast cancer, 1 colorectal carcinoma). One of the adult GBM and the 6 metastatic models were transduced for bioluminescent monitoring of tumor burden: 53% of tumors across model types were eliminated by TCE treatment, 39% showed tumor presence without progressive growth, and 8% of tumors continued to grow with or without an initial delay. Dose range tolerability in transgenic mice showed dose dependent pharmacodynamic effects on body weight, lymphopenia, cytokine stimulation, CD3+ cell biodistribution, and tissue PD-L1 expression with no overt toxicity. A dose range finding study in non-human primates revealed the TCE was well tolerated with pharmacodynamic responses observed at 0.03 mg/kg and limited to grade 1 toxicities. At 0.3 mg/kg grade 2-4 toxicities were observed.\nConclusion: Bispecific PD-L1:CD3 TCE is safe at doses that show efficacy in intracranial xenograft tumor models. This PD-L1 TCE presents a novel therapeutic strategy for patients with primary and metastatic intracranial tumors that are typically fatal.", "source_company": "Seattle Children's Research Institute", "source_org_type": "研究机构", "row_number": 459, "target_meta": "PDL1", "MOA_meta": "双特异性抗体"}, {"drug_name": "CBD-IL-12 armored STEAP1 CAR-T cells", "company": "Imperial College London", "org_type": "大学", "target": "STEAP1", "modality": "CAR", "importance_level": "中", "total_score": 61, "institution_score": 35, "track_score": 85, "milestone_score": 75, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "STEAP1靶向的CAR-T细胞通过条件性分泌胶原结合域融合的IL-12（CBD-IL-12）实现肿瘤局部富集，提升实体瘤尤其是前列腺癌的疗效并降低系统毒性。机构为大学非商业化顶级，赛道为热门CAR-T+装甲化改造且针对mCRPC未满足需求，preclinical显示强效肿瘤清除和免疫记忆故综合热度和潜力中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5190", "id": "UZ7ECZ0BZznHJdntvNYd", "source_drug_name": "CBD-IL-12 armored STEAP1 CAR-T cells", "title": "Collagen-binding IL-12-armored STEAP1 CAR-T cells for advanced prostate cancer", "abstract_text": "Metastatic castration-resistant prostate cancer (mCRPC) remains an incurable and immunologically cold solid malignancy. Six-transmembrane epithelial antigen of the prostate 1 (STEAP1) is highly expressed in over 85% of mCRPC tumors and represents an attractive therapeutic target. Although chimeric antigen receptor (CAR)-T cell therapy has revolutionized the treatment of hematologic cancers, its efficacy in solid tumors, including prostate cancer, has been limited by the immunosuppressive tumor microenvironment (TME) and heterogeneous antigen expression. Interleukin-12 (IL-12) has the potential to overcome these barriers by activating and recruiting immune cells into tumors and promoting epitope spreading to counter antigen heterogeneity. While armored CAR-T cells engineered to produce IL-12 have been developed, further refinement is needed to optimize both potency and safety. Autologous IL-12-producing T cell therapy has previously shown clinical activity in melanoma, but systemic toxicity constrained its use, indicating that IL-12 secreted by CAR-T cells, though locally produced, can still diffuse into circulation. Here, we present STEAP1-directed CAR-T cells engineered to conditionally secrete a collagen-binding domain-IL-12 fusion protein (CBD-IL-12) upon antigen engagement. We demonstrate that fusing IL-12 to a CBD markedly enhances its retention within prostate tumors while limiting systemic spread in mice. As a result, intra-tumoral levels of IFN-γ, CXCL9, and GM-CSF remained comparably high to those induced by IL-12, yet without associated elevations in serum alanine aminotransferase (ALT) or off-target T cell infiltration in healthy organs. Flow cytometry revealed increased infiltration of T cells, NK cells, and cross-presenting dendritic cells, together with reduced monocytic myeloid-derived suppressor cells, following treatment with CBD-IL-12-expressing STEAP1 CAR-T cells. Immunohistochemistry and spatial transcriptomic analysis confirmed increased immune infiltrates and activation of IL-12 pathway and antigen processing and presentation by major histocompatibility complex-I in the CBD-IL-12 CAR-T treated tumor. Further, tertiary lymphoid structure-related chemokine and chemokine receptors including cxcr4, cxcr5, cxcl12 and cxcl13 as well as co-stimulatory molecules such as cd80, cd86, cd40 and tnfsf4 were upregulated in the tumor. When combined with anti-PD-1 and anti-CTLA-4 antibodies, CBD-IL-12 armored CAR-T cells eradicated established prostate tumors in mice without preconditioning. The CAR-T therapy generated durable anti-tumor immune memory to STEAP1 and other antigens. Our findings suggest that CBD fusion can localize potent but toxic immunomodulators such as IL-12 to the tumor site, offering a promising strategy to improve the safety and effectiveness of CAR-T therapies for solid tumors.", "source_company": "Imperial College London", "source_org_type": "大学", "row_number": 595, "target_meta": "STEAP1", "MOA_meta": "其他"}, {"drug_name": "RedTail", "company": "Calidi Biotherapeutics", "org_type": "公司", "target": "未披露", "modality": "virotherapy", "importance_level": "中", "total_score": 61, "institution_score": 55, "track_score": 85, "milestone_score": 45, "field_heat_score": 75, "bonus_score": 5, "brief_reason": "RedTail为双重可编程溶瘤病毒平台，通过膜工程实现系统给药肿瘤靶向并局部递送BiTEs和免疫激活payload如IL-15 Superagonist，机制创新针对实体瘤T细胞治疗难题。公司为临床阶段小型biotech，赛道热门但仍处preclinical/早期开发。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10423", "id": "y1XM_5wBX1NQZOEH-LK6", "source_drug_name": "RedTail", "title": "Redtail: A dual-programmable virotherapy platform for systemic tumor targeting and localized gene delivery", "abstract_text": "RedTail is a next-generation gene therapy platform combining systemic delivery with tumor selectivity. Unlike conventional oncolytic viruses, RedTail integrates programmable targeting for precise tumor specificity and genetic payload delivery for immune modulation of the tumor microenvironment (TME). It employs a tumor-specific, replicating extracellular enveloped vaccinia virus (EEV) cloaked in a second human cell-derived membrane (the “Envelope”) from engineered host cell lines; chimeric CD55 overexpression in the Envelope confers resistance to complement and neutralizing antibodies, enabling systemic administration. The Envelope can be further designed to express targeting proteins. The viral genome can be modified to deliver immune-cell activating therapeutic payloads such as IL-15 Superagonist along with bispecific T-cell engagers (BiTEs) for localized expression in the tumor microenvironment. Delivering BITEs at high concentrations to the tumor while simultaneously activating T-cells in the TME through in situ expression of an immunostimulatory payload may overcome the challenges seen to date with T-cell engagers in solid tumors.\nMethods: RedTail EEVs were produced using engineered host cell lines expressing chimeric antigen receptors (CARs). The RedTail EEVs were further engineered to express BITEs and T-cell activating payloads at high concentrations in situ. Tumor targeting, viral amplification, and transgene expression were assessed by viral titers, ELISA, flow cytometry, and immunohistochemistry.\nResults: The first programmable characteristic of RedTail is its extracellular membrane. RedTail EEVs were manufactured using host cell lines engineered to express CARs, producing particles that displayed CARs (e.g., anti-HER2, anti-Trop2) on their surface with corresponding tropism.The second programmable characteristic is the viral genome, engineered to express genetic payloads including BiTEs targeting tumor antigens along with CD3 to recruit and activate T cells. A T-cell activating payload was also included. Viral infection was enhanced for tumor cells that displayed the cognate target, and resulted in tumor cell lysis along with high levels of expression of the BITE and the immune stimulating payload.This dual programmability—membrane engineering for targeting and genome programming for payload delivery—represents a unique approach among systemic virotherapies.\nConclusions: This dual programmability enables systemic tumor targeting, immune priming, and localized expression of both a T-cell engager and an immune priming payload, positioning RedTail as a next-generation systemic platform with a unique approach to T-cell targeting in solid tumors.", "source_company": "Calidi Biotherapeutics", "source_org_type": "公司", "row_number": 617, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "ProteanFect", "company": "Westlake University", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "中", "total_score": 61, "institution_score": 35, "track_score": 85, "milestone_score": 75, "field_heat_score": 80, "bonus_score": 4, "brief_reason": "ProteanFect为基于内源蛋白coacervate的非病毒基因递送平台，主要用于mRNA和基因编辑工具（Cas9 RNP、prime editing）的高效递送至干细胞，无明确单一靶点。大学机构得分较低，但基因编辑递送赛道热度高、preclinical数据优秀（HSC中BCL11A位点80%编辑率、无脱靶），综合潜力较强获中评。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5560", "id": "WVXM_5wBX1NQZOEH-LO6", "source_drug_name": "ProteanFect", "title": "The first coacervate based delivery system for efficient and safe genetic engineering in stem cells", "abstract_text": "Stem cell biology, which orchestrates embryogenesis, influences aging, and holds promise for revolutionary therapies, represents a central thread in human health. This underscores the pressing need for advanced delivery technologies to facilitate both research progress and clinical translation. Here, we harness coacervates-regarded as protocells during evolution-to develop a pioneering delivery platform. We identified a mammalian endogenous protein that encapsulates diverse nucleic acids through liquid-liquid phase separation (LLPS), forming protein-based coacervates. These coacervates exhibit superior mRNA encapsulation capacity, efficient cellular internalization, robust cytoplasmic cargo release, and broad compatibility across multiple cell types -including primary immune cells and stem cells. The resulting platform, named ProteanFect, supports diverse genetic cargoes for versatile gene manipulation strategies. ProteanFect demonstrated high versatility and efficiency across key stem cell types, including hematopoietic stem cells (HSCs), human embryonic stem cells (ESCs), and induced pluripotent stem cells (iPSCs) derived from diverse somatic sources such as PBMCs, urine, and adipocytes. It efficiently enabled gene overexpression and knockout through the delivery of mRNA or Cas9 RNP complexes. In a key demonstration of its therapeutic potential for hematological disorders, ProteanFect achieved approximately 80% allele modification at the BCL11A locus in HSCs, a strategy aimed at reactivating fetal hemoglobin to treat hemoglobinopathies, with no detectable off-target editing. Furthermore, the platform facilitated precise genetic correction by delivering prime editing tools into PBMC-derived iPSCs, achieving approximately 55% precise base substitution with high cell viability. In summary, ProteanFect constitutes a versatile, safe, and efficient non-viral platform that operates without synthetic lipids or electroporation. By enabling robust transient expression of reprogramming and gene-editing cargo without genomic integration, it provides a safer and more controllable pathway for cellular reprogramming, iPSC generation, and the development of next-generation cell therapies.", "source_company": "Westlake University", "source_org_type": "大学", "row_number": 711, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "chimeric killer immunoglobulin (KIR)-like receptor (cKIR) engineered T cells", "company": "University of Pennsylvania", "org_type": "大学", "target": "未披露", "modality": "CAR", "importance_level": "中", "total_score": 61, "institution_score": 45, "track_score": 85, "milestone_score": 55, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "cKIR CAR-T通过DAP12-independent机制（GRB2介导Ras/MAPK通路）实现增强抗肿瘤活性，机制新颖且优于传统CD3z CAR。机构为顶尖大学、赛道为热门CAR-T领域但仍处机制研究阶段，故综合为中等重要性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9584", "id": "clXM_5wBX1NQZOEH-LO6", "source_drug_name": "chimeric killer immunoglobulin (KIR)-like receptor (cKIR) engineered T cells", "title": "Understanding DAP12-independent antitumor activation in KIR-based CAR T cells", "abstract_text": "We previously described a chimeric killer immunoglobulin (KIR)-like receptor (cKIR) approach to modifying T cell antigenic specificity that mimics the multichain design of natural KIR immunoreceptors (Wang E et al. Cancer Immunol Res 2014). T cells modified to express a cKIR with the natural ITAM-containing adaptor, DAP12 that associates with activating KIRs, show significantly enhanced anti-tumor activity acrossmultiple solid tumor models when compared to traditional CD3z-based chimeric antigen receptors (CARs). However, unlike TCR, where assembly with ITAM-containing CD3 family members is required for plasma membrane expression, natural and chimeric KIR exhibit membrane expression in the absence of DAP12. We show that cKIR engineeredT cells also produce IFN-g and retain cytotoxic activity in the absence of DAP12, revealing previously unrecognized DAP12-independent signaling pathways. This is associated with phosphorylation of ERK, JNK and STAT3 at early time points (30-60 mins) following cKIR engagement with target antigen. Although the cytoplasmic domain of KIR2DS2 used in cKIR is short and lacks canonical signaling motifs, we hypothesized that this domain plays a functional role in T cells by recruiting alternative adaptors to promote noncanonical signaling in the absence of DAP12. Immunoprecipitation of cKIR in T cells lacking DAP12 identified GRB2 as an associated adaptor protein. CRISPR- mediated GRB2 knockout selectively abolished ERK activation, establishing GRB2 as a crucial link to the Ras/MAPK pathway in cKIR-activated T cells. Structure-functionanalysis of the KIR2DS2 cytoplasmic tail, containing one tyrosine, one threonine, and four serine residues, revealed that progressive truncation of these residues had minimal effect on membrane expression, but increasingly impaired cytotoxicity, cytokine production, proliferation, and downstream signaling with a > 25-fold loss of IFN-g andcytotoxicity observed with the truncation of C-terminal to serine residue 3. Collectively, these results suggest that DAP12-independent signaling by cKIR, mediated through GRB2 and likely other yet-to-be-identified adaptors, contribute to diverse signaling in T cells and may contribute to the enhanced anti-tumor function observed with KIR-based CAR T cells compared with conventional CAR designs.", "source_company": "University of Pennsylvania", "source_org_type": "大学", "row_number": 726, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "CD70-directed CAR T-cells", "company": "Champions Oncology, Inc.", "org_type": "公司", "target": "CD70", "modality": "CAR", "importance_level": "中", "total_score": 61, "institution_score": 45, "track_score": 85, "milestone_score": 55, "field_heat_score": 75, "bonus_score": 3, "brief_reason": "靶向CD70的CAR-T细胞针对实体瘤尤其是肾细胞癌，采用armored设计（dnTGFβRII）抵抗TME免疫抑制。机构为CRO类公司非头部药企得较低分，赛道为热门CAR-T实体瘤方向但仍preclinical工具平台验证阶段，得分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4420", "id": "EFXM_5wBX1NQZOEH-LS6", "source_drug_name": "CD70-directed CAR T-cells", "title": "CAR T-Cell therapy efficacy evaluation inTumorGraft3D tri-culture platform with reconstructed tumor microenvironment", "abstract_text": "Chimeric antigen receptor (CAR) T-cell therapy represents one of the most transformative innovations in cancer immunotherapy, offering the ability to redirect a patient’s own immune cells toward malignant targets through genetic engineering of tumor-recognizing receptors. While clinical successes in hematologic malignancies such as B-cell acute lymphoblastic leukemia & diffuse large B-cell lymphoma have validated the concept of CAR T-cell-mediated cytotoxicity, extending this efficacy to solid tumors has proven significantly more challenging due to the immunosuppressive nature of the tumor microenvironment (TME), the heterogeneity of antigen expression, &the presence of physical & biochemical barriers that limit CAR T-cell infiltration & persistence. To address these limitations, we developed the TumorGraft3D-Tri-Culture platform, a physiologically relevant ex-vivo system capable of recapitulating the complex interactions that occur among tumor cells, cancer-associated fibroblasts (CAFs), & immune suppressive components such as M2 macrophages. In this study, CD70-directed CAR T-cells were evaluated in a renal cell carcinoma with high CD70 expression. Standard targeted CAR T-cells expressing the CD27 receptor were compared to armored CAR T-cells incorporating a dominant-negative TGFβ receptor II (dnTGFβRII) designed to resist TGFβ-mediated immunosuppression. The tri-culture system consisted of tumor cells, cancer-associated fibroblasts (CAFs), & M2 macrophages, providing a physiologically relevant TME that supported tumor proliferation & cytokine-driven immune suppression. Addition of CAR T-cells enabled a quad-culture system used to assess therapeutic efficacy under suppressive conditions. Tumor cells were seeded at a 1x baseline ratio, with CAFs at 0.5x & M2 macrophages at 0.1-0.5x. Both targeted & armored CAR T-cells reduced tumor viability compared with controls, but armored CAR T-cells showed enhanced cytotoxicity & sustained activation. CD69 expression was markedly elevated in both CAR T-cell types, indicating robust activation, while CD70 surface expression on tumor cells decreased following treatment, reflecting target engagement & selective killing. Brightfield imaging & luminescence analyses confirmed significant tumor lysis, especially in armored CAR T-cell groups. The 3D platform successfully recapitulated stromal & immune-mediated resistance mechanisms absent in conventional two-dimensional systems, validating its translational relevance. These findings demonstrate that TGFβ-resistant armored CAR T-cells maintain effector function within an immunosuppressive TME & highlight CD70 as a viable & selective therapeutic target. Collectively, this work establishes the TumorGraft3D tri-culture platform as a robust preclinical tool for evaluating & advancing next-generation CAR T-cell therapies in solid tumors.", "source_company": "Champions Oncology\nChampions Oncology, Inc.", "source_org_type": "公司", "row_number": 843, "target_meta": "CD70", "MOA_meta": "其他"}, {"drug_name": "ChAdOx1", "company": "National Cancer Institute", "org_type": "研究机构", "target": "未披露", "modality": "viral vector vaccine", "importance_level": "中", "total_score": 61, "institution_score": 45, "track_score": 75, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "ChAdOx1/MVA异源 prime-boost病毒载体疫苗在难治性胶质母细胞瘤模型中诱导脑组织驻留记忆T细胞（TRM）介导显著抗肿瘤免疫，靶点未明确披露。机构为研究机构得分一般，但疫苗诱导脑TRM的长效组织特异性免疫记忆及过继转移验证机制为亮点，赛道与胶质瘤领域临床潜力支撑中等重要性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3638", "id": "MlXM_5wBX1NQZOEH-LS6", "source_drug_name": "ChAdOx1", "title": "Viral vector vaccination induces brain resident memory T cells to drive anti-glioblastoma immunity", "abstract_text": "Glioblastoma is a lethal brain tumor notable for limited spontaneous induction of CD8+ T cell responses. While viral-vector vaccines can drive particularly high magnitudes of tumor-reactive T cells, they have not been investigated for the treatment of glioblastoma. Here, we demonstrate that heterologous prime-boost vaccination with the simian adenovirus ChAdOx1 and poxvirus modified vaccinia Ankara (MVA) treats the orthotopic, syngeneic, checkpoint-inhibitor refractory SB28 murine model of glioblastoma, both in the context of the murine tumor antigen, P1A, and a newly identified tumor-associated antigen expressed by SB28. Adjuvant anti-PD-1 and anti-CTLA-4 did not further improve outcomes. Vaccination induced immunoediting of tumor antigen expression and tumor-specific recruitment of antigen-specific T cells to challenged brains, the majority of which had a CD103+CD69+CD8+ tissue resident memory (TRM)-like phenotype. While induction of TRMs by vaccination has been implicated in superior control of other cancers, their role in mediating anti-glioblastoma immunity was unclear. ChAdOx1/MVA-induced brain TRMs displayed superior polyfunctionality compared to circulating and non-TRM brain antigen-specific CD8+ T cells. Long-term surviving mice maintained consistent levels of antigen-specific TRM cells in their brains at days 70 and 175 post-tumor challenge, despite a three-fold decrease in circulating antigen-specific T cells, indicating durable T cell memory in the brain parenchyma. Furthermore, survivors were protected against a second orthotopic, but not subcutaneous, tumor rechallenge, demonstrating tissue-specific immunological memory. Intracranial adoptive transfer of brain-derived antigen-specific TRMs isolated from vaccinated, tumor-bearing mice was sufficient to prolong the survival of naïve mice challenged with tumors, whereas blood-derived antigen-specific non-TRMs and non-antigen-specific brain-derived CD8⁺ T cells were not. Despite peripheral administration of the vaccines, antigen-specific CD8+ T cells were induced not only in the brains of tumor-free animals, but in many tissues, including the liver, lung, skin, skull bone marrow, and meninges, with distinct phenotypes observed in different tissues. Overall, we demonstrate that ChAdOx1/MVA vaccination is a potent strategy to induce TRMs to mediate anti-glioblastoma immunity, establishing a basis for further clinical investigation of ChAdOx1/MVA vaccination to treat patients with glioblastoma.", "source_company": "National Cancer Institute", "source_org_type": "研究机构", "row_number": 868, "target_meta": "not available", "MOA_meta": "病毒载体疫苗"}, {"drug_name": "ProteanFect", "company": "Westlake University", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "中", "total_score": 61, "institution_score": 35, "track_score": 85, "milestone_score": 75, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "ProteanFect为基于内源蛋白的coacervate非病毒递送系统，主要解决免疫细胞（如CAR-T）基因递送难题，实现高效率mRNA/DNA/siRNA/CRISPR递送。大学背景拉低机构分，但热门非病毒递送+细胞治疗工程赛道热度高，前临床数据优秀且广适用性带来较强转化潜力。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9694", "id": "k1XM_5wBX1NQZOEH-LS6", "source_drug_name": "ProteanFect", "title": "A versatile coacervate based delivery system to overcome engineering barriers in immune cells", "abstract_text": "The clinical translation of immune cell engineering (e.g., CAR-T, TCR-T) and functional genomics research in hematologic malignancies are significantly hampered by the limitations of existing gene delivery systems. Viral vectors raise safety and cost concerns, while conventional non-viral methods often suffer from low efficiency and high cytotoxicity, particularly in primary immune cells and refractory hematopoietic cell lines. To overcome these barriers, we developed ProteanFect, the first endogenous protein-based coacervate delivery system. This platform is designed for high-efficiency delivery of diverse genetic payloads, including mRNA, DNA, siRNA, and CRISPR/Cas9 components (mRNA or RNP), enabling robust gene expression and precise gene editing. In primary human immune cells, ProteanFect achieved >90% mRNA transfection efficiency (e.g., GFP mRNA in T cells) with sustained transgene expression and maintained over 90% cell viability. It enabled the generation of functional anti-CD19 CAR-T cells that effectively suppressed tumor growth in vivo. Furthermore, ProteanFect demonstrated high-precision gene editing, achieving 88% knockout efficiency at the TRAC locus in primary T cells via Cas9 mRNA/sgRNA delivery. The platform also showed broad applicability, attaining >70% and >65% transfection efficiencies in natural killer (NK) cells and B cells, respectively, and robust performance in mouse primary immune cells. Simultaneously, ProteanFect effectively addressed transfection challenges in hard-to-transfect hematopoietic cell lines (e.g., Jurkat, K562, THP1, HL-60, Raji, Kasumi-1). It achieved 70-90% RNA and 40-70% DNA transfection efficiency, supported large plasmid (~15.7 kb) delivery with >50% efficiency, and enabled ~70% siRNA-mediated knockdown and ~80% CRISPR/Cas9-mediated knockout in Jurkat cells. Even in more refractory lines, RNA transfection efficiency reached ~80%. The system also facilitated co-transfection and multiplexed gene editing, highlighting its versatility. In summary, ProteanFect represents a transformative non-viral platform that uniquely synergizes high-efficiency nucleic acid delivery with precise gene editing capabilities, all while maintaining minimal cytotoxicity and demonstrating broad applicability across primary human and mouse immune cells as well as challenging hematologic cell lines. Its versatile support for diverse payloads—from mRNA and large plasmids to CRISPR RNP complexes—positions this technology as a pivotal tool that not only accelerates the production of engineered cell therapies but also expands the frontiers of basic research, functional genomics, and therapeutic development in immunology and hematology.", "source_company": "Westlake University", "source_org_type": "大学", "row_number": 937, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "CRISPR activation (CRISPRa)", "company": "Stanford University", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "中", "total_score": 61, "institution_score": 40, "track_score": 85, "milestone_score": 70, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "CRISPRa作为工具平台用于高通量筛选发现RNA-based机制以增强癌细胞对T细胞毒性的敏感性，靶点未明确披露但涉及免疫调控新途径；斯坦福大学学术机构分较低，但CRISPRa在肿瘤免疫和RNA免疫治疗赛道热度高，结合in situ Perturb-seq等创新平台显示较强preclinical价值和潜在RNA-based免疫治疗前景。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/7815", "id": "eJ7ECZ0BZznHJdntvNYd", "source_drug_name": "CRISPR activation (CRISPRa)", "title": "High content CRISPR activation screens identified synthetically lethal RNA-based mechanisms to sensitize cancer cells to targeted T cell cytotoxicity", "abstract_text": "T cells recognize cancer (neo)antigens via T cell receptor (TCR) and selectively eliminate the target cancer cells, yet cancer cells often evolve evasion mechanisms or lack sensitizing cues that limit the efficacy of immunotherapy. While cancer CRISPR knockout screens have revealed genes whose loss drives immune evasion, far less is known about gain-of-function mechanisms capable of restoring tumor susceptibility to targeted T cell cytotoxicity. To address this gap, we developed an integrated framework combining CRISPR activation (CRISPRa), single-cell transcriptomics, and a new optical pooled high-content screening approach to uncover RNA-based mechanisms that sensitize cancer cells to TCR-specific cytotoxicity. In melanoma cells, CRISPRa screens uncovered functionally diverse regulators of T-cell killing, including the chromatin remodeler SAFB and additional sensitizing genes that restore susceptibility in cancer and virally infected cells. To decode how these regulators act within the native tumor context, we developed in situ Perturb-seq, a pooled optical genetic screening platform that enables single-molecule spatial transcriptomic readouts directly in intact tissues. In situ Perturb-seq, together with Perturb-seq, revealed that sensitizing perturbations converge on shared cell-autonomous and intercellular programs involving stemness-differentiation axes, cytokine networks, and ligand-receptor circuits. Notably, Wnt ligands that were found as sensitizing hits in cancer cells significantly enhanced T-cell effector functions, demonstrating how tumor-intrinsic gain-of-function perturbations can identify new modalities to reprogram and engineer T cells. Together, this work introduces a scalable platform to identify RNA-based immunomodulators and resolve their multicellular mechanisms across scales. By coupling CRISPRa screens with in situ Perturb-seq, we establish a broadly applicable framework for discovering and mechanistically defining gene activations that re-sensitize tumors to cytotoxic immune attack - including applicability beyond T cells to innate cytotoxic lymphocytes such as natural killer (NK) cells - and across distinct solid tumor types, thus opening avenues for RNA-based immunotherapies for disease treatment and prevention.", "source_company": "Stanford University", "source_org_type": "大学", "row_number": 952, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "CD19-targeting CAR", "company": "GemPharmatech Co., Ltd.", "org_type": "公司", "target": "CD19", "modality": "CAR", "importance_level": "中", "total_score": 61, "institution_score": 45, "track_score": 85, "milestone_score": 55, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "CD19靶向CAR属于经典热门靶点和细胞治疗赛道，in vivo递送（LNP和慢病毒）展示强劲肿瘤抑制效果。GemPharmatech作为国内CRO模型公司而非头部药企，preclinical平台验证阶段，综合热度中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/7159", "id": "c57M_5wBZznHJdnt_W3O", "source_drug_name": "CD19-targeting CAR", "title": "Robust in vivo CAR-T efficacy evaluation in a PBMC-reconstituted NCG-MHC-dKO model with delayed GVHD", "abstract_text": "Background: Humanized mouse models are critical for evaluating in vivo CAR-T therapies, but their utility is limited by rapid onset Graft-versus-Host Disease (GVHD). We employed a novel NCG-MHC-dKO model to mitigate GVHD, enabling prolonged assessment of anti-tumor efficacy for different in vivo CAR-T modalities. Methods: The NCG-MHC-dKO model was reconstituted with human PBMCs, confirming delayed GVHD. Mice bearing Nalm-6 tumors were treated with a single dose of either a lentiviral vector or an LNP formulation delivering a CD19-targeting CAR. Tumor growth was monitored via bioluminescence imaging. Results: The PBMC-NCG-MHC-dKO model demonstrated a significantly extended observation window due to postponed GVHD. In this model, both lentiviral and LNP-based in vivo CAR-T therapies potently suppressed Nalm-6 tumor growth. Functional CAR-T cells generated in vivo were detected and expanded in treated mice. Conclusion: The PBMC-reconstituted NCG-MHC-dKO model provides a robust and durable platform for in vivo CAR-T evaluation by overcoming early GVHD. We successfully validated its utility for both lentiviral and LNP delivery platforms, demonstrating significant and comparable anti-tumor efficacy.", "source_company": "GemPharmatech Co., Ltd.", "source_org_type": "公司", "row_number": 1027, "target_meta": "CD19", "MOA_meta": "其他"}, {"drug_name": "novel therapeutic antibodies", "company": "MIMETAS B.V", "org_type": "公司", "target": "未披露", "modality": "therapeutic antibodies", "importance_level": "中", "total_score": 61, "institution_score": 65, "track_score": 75, "milestone_score": 40, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "靶点为PVM释放的抑制免疫迁移的蛋白（具体未披露），通过抗体阻断其作用以恢复T细胞迁移，属于肿瘤免疫抑制微环境新靶向策略。MIMETAS为专注器官芯片模型的中小型biotech公司，非头部药企，得分中等；赛道为肿瘤微环境+抗体热门但仍preclinical模型验证阶段，里程碑仅in vitro初步有效性，综合热度中偏上，总分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5108", "id": "PJ7M_5wBZznHJdnt_W7O", "source_drug_name": "novel therapeutic antibodies", "title": "Therapeutic antibody inhibits target-mediated immune migration in advanced in-vitromodelofanimmune suppressive tumormicroenvironment", "abstract_text": "It has become increasingly clear that current immune-oncology treatments are inadequate in generating sufficient targeted treatment effects without damaging the surrounding tissue. Rather than focusing on the tumor as the main target, the immune suppressive tumor microenvironment has recently become a novel therapeutic target as it drives tumor growth, therapy resistance and metastasis. However, current in vitro systems often fail to replicate the tumor microenvironment hindering accurate efficacy evaluation. This study used an advanced in-vitro model of an immune suppressive tumor microenvironment to study treatment effects of therapeutic antibodies. Here we report on the use of an organ-on-a-chip based model to study immune cell migration in the context of a subset of immune suppressive macrophages, known as perivascular macrophages (PVM), and on a target protein released by these cells. The model contains an endothelial vessel (HUVEC), macrophages (PVM or M1) and immune cells (PBMCs or T cells) to study the interaction between these cells and determine the effect of target protein and antibodies. The level of immune cell migration showed to be dependent on the activation state of immune cells and pretreatment of the endothelium. PVMs shown to have an inhibitory effect on immune cells migration, in contrast to M1 macrophages that increased the number of migrated immune cells. The released target protein was found to reduce T cell migration, specifically for stimulated T cells. Finally, novel therapeutic antibodies were assessed after addition of the target protein. For one of the antibodies increased migration of stimulated T cells was observed. These findings highlight the potential of targeting PVMs and their released proteins, as important elements of an immune suppressive microenvironment. Additionally, the study shows the utility of the advanced in-vitro model for evaluating therapeutic antibodies. In the future the system will be used for testing additional therapeutics in the context of an immune suppressive tumor microenvironment.", "source_company": "MIMETAS B.V", "source_org_type": "公司", "row_number": 1165, "target_meta": "not available", "MOA_meta": "抗体"}, {"drug_name": "2'3'-cGAMP-OVA-SNALPs", "company": "King's College London", "org_type": "大学", "target": "未披露", "modality": "mRNA", "importance_level": "中", "total_score": 61, "institution_score": 35, "track_score": 85, "milestone_score": 75, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "该纳米疫苗采用mRNA编码抗原OVA并共递送STING激动剂2'3'-cGAMP，属于mRNA+先天免疫激活的热门癌症治疗疫苗赛道。机构为大学得分较低，但平台显示较强的preclinical疗效（包括治疗性肿瘤消退）和转化潜力，故综合评为中等重要性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5552", "id": "kp7M_5wBZznHJdnt_W7P", "source_drug_name": "2'3'-cGAMP-OVA-SNALPs", "title": "A STING-boosted lipid nanoparticle mRNA vaccine for therapeutic cancer vaccination", "abstract_text": "Despite the success of immunotherapies and preventative vaccines in virus-associated cancers, the translation of therapeutic vaccination has been limited, often by limited immunogenicity and inability to overcome the immunosuppressive ‘cold’ tumor microenvironment. Recent advances in mRNA vectors for viral immunization, and optimized nanoparticle delivery, have renewed promise for cancer vaccination. In this study, we developed an ionizable stable nucleic acid lipid nanoparticle (SNALP) nanovaccine for the delivery of mRNA-encoded model antigen, ovalbumin (OVA). To counter tumor-associated immunosuppression, we harnessed the innate anti-viral stimulator of interferon genes (STING) pathway by co-encapsulating cyclic dinucleotide STING agonist 2’3’-cGAMP. SNALP formulations were optimized for biocompatibility and cell uptake, with small particle size, near-neutral surface charge, and high encapsulation efficiency of both mRNA and 2’3’-cGAMP within a single platform. SNALP-mediated co-delivery achieved effective mRNA transfection and antigen presentation in primary dendritic cells (DCs) in vitro, whilst addition of 2’3’-cGAMP enhanced DC maturation and activation, noted by increased co-stimulatory (CD80, CD86) and MHC-I (H-2Db, H-2Kb) marker expression. Nanovaccine-activated DCs efficiently primed naïve primary CD8+ T cells to elicit effector function and replicate in co-culture. In vivo, immunization with 2’3’-cGAMP-boosted OVA-SNALPs elicited a robust immunological T cell response, evidenced by circulating antigen-specific CD8+ T cell populations with central memory phenotypes, and effector splenic CD8+ T cells capable of TCR-mediated cytokine production upon challenge. Therapeutic relevance of 2’3’-cGAMP-OVA-SNALPs was assessed in murine models of melanoma expressing OVA (B16F10-OVA) under different vaccination protocols. The nanovaccine consistently delayed tumor onset and extended survival, completely preventing tumor formation when given prophylactically, or driving total tumor regression when given therapeutically by local (intra-tumoral) or systemic (intra-muscular) routes, in a subset of animals, which was not found in non-adjuvanted controls. Some tumor control was also noted upon therapeutic administration of SNALPs containing irrelevant mRNA, highlighting potentially beneficial innate adjuvancy of the platform itself. Altogether, this work shows that SNALP-based nanovaccines are a versatile and translatable platform for next-generation cancer immunotherapy. The nanovaccine showed potential as a monotherapy, converting immunologically ‘cold’ tumors into responsive microenvironments. This adaptable system enables co-delivery of antigens and immune modulators to target immunosuppressive and induce durable anti-tumor responses. Future studies will explore combining it with additional immunotherapies to improve clinical efficacy.", "source_company": "King's College London", "source_org_type": "大学", "row_number": 1223, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "CD3×CD20 TCE", "company": "Shanghai ChemPartner Co., Ltd.", "org_type": "公司", "target": "CD3×CD20", "modality": "bispecific antibody", "importance_level": "中", "total_score": 60.5, "institution_score": 45, "track_score": 85, "milestone_score": 60, "field_heat_score": 75, "bonus_score": 2, "brief_reason": "该CD3×CD20双特异性T细胞衔接器（TCE）针对Burkitt淋巴瘤，在人源化PBMC小鼠模型中显示显著肿瘤消退，优于PD-1抑制剂；靶点CD20在B细胞恶性肿瘤中成熟且热门，TCE赛道热度高，但研发机构为CRO服务型公司而非自主管线主导的头部药企，前期体外+体内preclinical数据较扎实但无临床阶段。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6346", "id": "Np7M_5wBZznHJdnt_W3O", "source_drug_name": "CD3×CD20 TCE", "title": "Characterization and preclinical efficacy of a CD3×CD20 bispecific T cell engager in a humanized PBMC mouse model", "abstract_text": "Immuno-oncology (IO) therapies aim to harness and amplify the body’s immune system to recognize, control, and destroy cancer cells. One key therapeutic goal in IO is to enhance T cell-mediated tumor killing. Currently established strategies include immune checkpoint inhibitors (ICIs), which release inhibitory brakes on T cells; T cell receptor-engineered T cell (TCR-T) therapies, which improve surface and intracellular antigen recognition; and chimeric antigen receptor (CAR) T cell therapies, which provide synthetic tumor antigen specificity. While these approaches have achieved success, they also face challenges such as T cell exhaustion, antigen escape, and safety and toxicity concerns, including cytokine release syndrome. Another emerging class of T cell-redirecting therapies are T cell engagers (TCEs); bi- or tri-specific antibodies that physically link T cells to tumor-associated antigens (TAAs). This interaction triggers robust T cell activation and a cascade of cytotoxic events culminating in tumor cell apoptosis. FDA-approved TCEs, such as Epcoritamab (CD3xCD20) for relapsed or refractory diffuse large B-cell lymphoma (DLBCL), Blinatumomab (CD3×CD19) for acute lymphoblastic leukemia (ALL) and Teclistamab (CD3×BCMA) for multiple myeloma, have demonstrated significant clinical efficacy in these respective diseases. While TCEs have shown success in treating hematologic malignancies, their role in Burkitt’s lymphoma, an aggressive B-cell non-Hodgkin lymphoma linked to Epstein-Barr virus and MYC dysregulation, remains unexplored. Burkitt’s lymphoma is generally considered highly curable using CD20 antibody-based immunotherapy, however resistance to anti-CD20 therapy is emerging, potentially linked to immune effector depletion and exhaustion from continuous intensive treatment. To investigate the efficacy of TCEs in Burkitt’s lymphoma, we characterized a CD3×CD20 TCE using in vitro binding and cytotoxicity assays, and evaluated its therapeutic activity using an in vivo Raji xenograft model (cell line of Burkitt’s lymphoma origin, expressing CD19/CD20) in humanized PBMC NOG mice. The CD3×CD20 TCE showed the most potent binding to Raji cells in vitro. Furthermore, in the humanized Raji model, the CD3×CD20 TCE achieved significant tumor regression in the high-dose group, and a partial response was observed in the low-dose group. Furthermore, both low and high doses of TCE resulted in a greater reduction in tumor volume compared to the ICI Toripalimab, a humanized PD-1 monoclonal antibody. Evidence of body weight loss (BWL) was observed in the groups that had PBMCs administered (tumour bearing animals), suggesting that the BWL is linked to the model and PBMC rather that the treatment. These findings highlight the potential of CD3×CD20 TCEs as an alternative strategy for treatment of Burkitt’s lymphoma.", "source_company": "Shanghai ChemPartner Co., Ltd.", "source_org_type": "公司", "row_number": 81, "target_meta": "CD3,CD20", "MOA_meta": "双特异性抗体"}, {"drug_name": "CAMV-01", "company": "Cambium Oncology, LLC", "org_type": "公司", "target": "VPAC1", "modality": "other", "importance_level": "中", "total_score": 60.5, "institution_score": 45, "track_score": 75, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 5, "brief_reason": "CAMV-01为新型VIP受体（VPAC1）拮抗剂融合Fc的first-in-class免疫检查点抑制剂，针对AML中VIP介导的免疫抑制机制。机构为早期preclinical小biotech公司得45分，赛道新型免疫检查点+peptide-Fc融合有一定热度得75分，数据显示强效T细胞激活、多模型生存改善及优异PK（半衰期数周）得65分，综合潜力中等得总分60.5为中重要性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5257", "id": "dVXM_5wBX1NQZOEH-LO6", "source_drug_name": "CAMV-01", "title": "A first in class VIP receptor antagonist as an immunotherapeutic for acute myeloid leukemia", "abstract_text": "Current immune checkpoint therapies targeting PD-1 and PD-L1 are ineffective in treating Acute Myeloid Leukemia (AML). Vasoactive Intestinal Peptide (VIP) is an immunosuppressive 28-amino acid neuropeptide overexpressed in nearly 30% AML patients, suggesting that some AML tumors may be using VIP expression as a mechanism to evade immune surveillance. We hypothesize that AML cells secrete VIP which signals through the VIP-R (receptor) on T cells to limit anti-cancer immunity. Therefore, targeting the VIP signaling with a VIP-R antagonist can reverse immunosuppression and potentiate anti-cancer immunity. Using in silico modeling, in vitro screening for potentiation of T cell activation, and proof-of-principle screening in mouse leukemia models, we identified a novel VIP-R antagonist, ANT308. ANT308 shows stronger binding affinity to VIP-R as compared to VIP and potentiates activation of human and mouse T cells with an EC50 in the range of 200-400 nM. Immunofluorescence assays show that ANT308 colocalizes with the VIP receptor, VPAC1. Co-IP and flow cytometry confirmed ANT308 binding to VPAC1. In addition, ANT308 treatment of leukemic mice induced strong T cell-mediated anti-leukemic activity. To improve the pharmacokinetics of ANT308, we have developed a novel fusion peptide combining ANT308 and Fc fragment of IgG4 named CAMV-01. In a Jurkat T-cell activation assay, CAMV-01 has an EC50 of 100-200 nM and reduces T cell exhaustion. Furthermore, CAMV-01 significantly improved survival in multiple murine leukemia models, including those that secrete VIP (C1498) and the VIP negative cell line P815. In vitro stability studies show that CAMV-01 remains stable in plasma for > 4 days, whereas the ANT308 peptide is stable for only 15 minutes. PK studies with intravenous (i.v.) or subcutaneous (s.c.) injection of 15mg/kg CAMV-01 show a half-life of 2 weeks in mice, compared to 15 minutes for the ANT308 peptide. Using Sprague-Dawley rats receiving a single i.v. or s.c injection of 5mg/kg CAMV-01, the Cmax and t1/2 were estimated to be 82 nM and 165 hours (i.v.) respectively and 0.7 nM and 235 hours (s.c.) respectively. In a P815 mouse model, s.c. administration of CAMV-01 induced a stronger tetramer-positive CD8+ T-cell response compared to ANT308. In conclusion, CAMV-01 is a novel, first-in-class immunotherapeutic targeting the VIP immune checkpoint, with a robust pharmacokinetic and pharmacodynamic profile and promising potential for the treatment of AML.", "source_company": "Cambium Oncology, LLC", "source_org_type": "公司", "row_number": 240, "target_meta": "VIPR1", "MOA_meta": "其他"}, {"drug_name": "on-demand GLUT3 CAR-T cells", "company": "National Cancer Center Japan", "org_type": "研究机构/医院", "target": "未披露", "modality": "CAR", "importance_level": "中", "total_score": 60.5, "institution_score": 45, "track_score": 75, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 4, "brief_reason": "该CAR-T通过NFAT驱动的on-demand GLUT3表达显著改善实体瘤（胶质母细胞瘤）代谢适应性和抗肿瘤效能，同时避免毒性，是CAR-T在实体瘤领域的新策略优化。机构为日本国家癌症中心（研究型），非头部药企导致机构分较低，但概念创新+热门CAR赛道+较强preclinical肿瘤控制数据使其整体重要性达中等偏上。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3671", "id": "9lXM_5wBX1NQZOEH-LC5", "source_drug_name": "on-demand GLUT3 CAR-T cells", "title": "On-demand GLUT3 expression augments CAR-T cell metabolic fitness and antitumor efficacy while preventing toxicity in glioblastoma models", "abstract_text": "The clinical success of chimeric antigen receptor T (CAR-T) cell therapy in hematologic malignancies has prompted its application to refractory solid tumors, including glioblastoma (GBM). However, CAR-T cell efficacy against solid tumors remains modest. Here, we demonstrate that the dysfunction of CAR-T cells in GBM is attributed to glucose deficiency in the tumor microenvironment (TME) and that on-demand, but not continuous, metabolic replenishment significantly improves the antitumor efficacy of CAR-T cells. Massive consumption of glucose by cancer cells reduces the glucose level in the TME of GBM, consequently impairing CAR-T cells. Modifying CAR-T cells with stable expression of GLUT3, a high-affinity glucose transporter restored their cytokine production and killing activity. However, while CAR-T cells with stable GLUT3 expression induced tumor reduction in a GBM model, their overactivation led to T-cell apoptosis, exhaustion, and terminal differentiation as well as adverse events and mouse death. On-demand GLUT3 CAR-T cells, in which GLUT3 transcription is driven by the nuclear translocation of nuclear factor of activated T-cells (NFAT) by target antigen stimulation, exhibit enhanced metabolic fitness and increased antitumor efficacy, leading to long-lasting tumor control in intracranial human GBM cell xenograft models while preventing adverse events. Cognitive dysfunction testing and histological analysis using a neuron damage marker, fluoro-Jade C (FJC), in mice treated with on-demand GLUT3 CAR-T cells did not show any signs of toxicity. We propose that on-demand, but not stable, metabolic fitness, such as at the time of exposure to tumor antigens, is a novel concept for maximizing the antitumor efficacy of CAR-T cells against solid tumors.", "source_company": "National Cancer Center Japan", "source_org_type": "研究机构\n医院", "row_number": 300, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "α-helical L-PPOB50-G", "company": "University of Illinois at Urbana-Champaign", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "中", "total_score": 60.5, "institution_score": 35, "track_score": 85, "milestone_score": 75, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "该多肽作为自佐剂递送neoantigen mRNA的载体，同时激活DC并改善抗肿瘤免疫，无明确药物靶点。大学背景得分较低，但mRNA癌症疫苗+自佐剂创新机制处于高热度赛道，前临床数据显著优于对照、显示肿瘤清除潜力。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9681", "id": "mVXM_5wBX1NQZOEH-LG6", "source_drug_name": "α-helical L-PPOB50-G", "title": "Self-adjuvanting α-helical polypeptide simultaneously delivers neoantigen mRNAs and activates dendritic cells to eradicate tumors", "abstract_text": "mRNA-based vaccines have demonstrated tremendous success during the era of COVID-19, but their therapeutic potential for treating cancer, especially poorly immunogenic solid tumors, remains under-achieved. Herein we report a class of self-adjuvanting α-helical polypeptides that can markedly improve the antitumor efficacy of tumor neoantigen-encoding mRNAs. Ideal carriers for antigen-encoding mRNAs should not only facilitate antigen expression in DCs but also activate DCs and induce effective processing and presentation of expressed antigens. Herein we report the development of cationic α-helical polypeptides as a self-adjuvanting delivery vehicle for antigen-encoding mRNAs.\nThe α-helical polypeptides facilitate intracellular delivery of mRNAs into dendritic cells (DCs) via temporary membrane disruption, simultaneously activate DCs by regulating NF-κB and IRF pathways, and improve the ability of DCs to process and present mRNA-encoded neoantigens. The cationic polypeptide condenses and stabilizes mRNAs, promotes internalization via its cell-penetrating property, and increases the expression of activation markers (CD86, MHCII, CD40, and CCR7) on DCs by upregulating NF-κB, IRF, and STING pathways. Molecular docking and simulation confirm the stable complexation between mRNA and α-helical polypeptides.\nUpon subcutaneous administration, the polyplex migrates to draining lymph nodes, where it transfects and activates DCs, eliciting a strong neoantigen-specific cytotoxic T lymphocyte (CTL) response in vivo. Compared to mRNA-SM102 lipid nanoparticles or Lipofectamine 3000 lipoplexes, the polyplex enhances antigen expression and presentation by DCs, leading to significantly improved priming of antigen-specific CD8⁺ T cells in vitro and in vivo. The polyplex achieves 83.3% and 33.3% tumor-free survival in E.G7-OVA lymphoma and 4T1 triple-negative breast cancer (TNBC), respectively. This is far exceeding the 0% tumor-free survival of conventional formulations. Polyplexes composed of α-helical L-PPOB50-G and mRNAs encoding 4T1 TNBC neoantigens elicit potent neoantigen-specific CD8⁺ T cell responses while showing no detectable toxicity in major organs.\nThe polyplex also reprograms the immunosuppressive tumor microenvironment by enriching DCs, M1-phenotype CD86⁺ macrophages, and CD8⁺ T cells in tumors. We also observed increased PD-1 expression on intratumoral CD8⁺ T cells and PD-L1 on 4T1 tumor cells after polyplex treatment and demonstrated synergistic effects between the polyplex vaccine and anti-PD-1 therapy. Our polyplex system provides a facile and generalizable approach to developing robust mRNA-based cancer vaccines.", "source_company": "University of Illinois at Urbana-Champaign", "source_org_type": "大学", "row_number": 415, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "novel CRBN binders", "company": "HitChem", "org_type": "公司", "target": "CRBN", "modality": "other", "importance_level": "中", "total_score": 60.5, "institution_score": 55, "track_score": 90, "milestone_score": 40, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "新型疏水性CRBN结合剂用于分子胶降解剂开发，具有增强疏水性和独特结构特征，可扩展CRBN偏向化学空间并加速新靶点发现。HitChem作为专注早期hit发现的中小型biotech公司在热门分子胶赛道有一定技术积累，但仍处于工具化合物/库构建的preclinical早期阶段，无明确临床推进价值。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6461", "id": "hVXM_5wBX1NQZOEH-LK6", "source_drug_name": "novel CRBN binders", "title": "Design and applications of novel hydrophobic CRBN binders", "abstract_text": "Cereblon (CRBN) molecular glue degraders engage target proteins through a shallow binding pocket, representing a promising strategy to expand the druggable proteome. However, a key challenge in the structure-based discovery of CRBN molecular glues lies in the conformational diversity induced at the CRBN-substrate interface. Different CRBN binders can modulate this interface in distinct ways, ultimately determining which substrate proteins are recruited and defining compound selectivity.In this study, we designed and identified several novel CRBN binders exhibiting excellent or acceptable binary binding affinities. Compared with previously reported CRBN ligands, our compounds possess unique structural features and enhanced hydrophobic properties. Derivatives based on these scaffolds enabled the construction of a CRBN molecular glue library that extends into previously unexplored, CRBN-biased chemical space. This library provides a high-quality toolbox to accelerate the discovery of new targets using the CRBN molecular glue degrader approach.", "source_company": "HitChem", "source_org_type": "公司", "row_number": 572, "target_meta": "CRBN", "MOA_meta": "其他"}, {"drug_name": "mechano-optimized TCRs", "company": "Zhejiang University", "org_type": "大学", "target": "KRAS-G12D (pMHC)", "modality": "TCR-T", "importance_level": "中", "total_score": 60.5, "institution_score": 35, "track_score": 85, "milestone_score": 75, "field_heat_score": 80, "bonus_score": 6, "brief_reason": "基于力学优化原理设计的新一代TCR工程平台，以KRAS-G12D为模型展示显著提高特异性、敏感性和体内外抗瘤活性。大学机构得分较低，但热门TCR-T赛道、优秀preclinical数据及IND-enabling阶段推进带来较高综合潜力。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4539", "id": "vFXM_5wBX1NQZOEH-LK6", "source_drug_name": "mechano-optimized TCRs", "title": "Mechano-dynamic-principle-driven rational design of next-generation TCRs with high specificity and sensitivity", "abstract_text": "Background: Naturally evolved T-cell receptors (TCRs) achieve extraordinary antigen specificity through a flexible binding interface that forms force-stabilized catch bonds with cognate peptide-MHC (pMHC) complexes. This critical mechano-regulatory feature is often lost in conventional high-affinity engineered TCRs, whose rigid interfaces can paradoxically cause cross-reactivity with self-antigens and off-target toxicity, a major barrier to safe TCR-based immunotherapies.\nPurpose: Building on our prior elucidation of this mechano-regulation mechanism, we aimed to establish a novel engineering platform for designing next-generation TCRs—including TCR mimics, TCR-engineered cells (TCR-T), and T cell engagers (TCEs)—with enhanced specificity and sensitivity, using the KRAS-G12D neoantigen (presented by HLA-A*11:01) as a proof of concept.\nMethods: Following an initial screen, top-performing TCR clones were selected for comprehensive characterization. We evaluated their biophysical binding and in vitro function (single-molecule force spectroscopy, kinetic-functional mapping, serial tumor killing, memory phenotype differentiation), in vivo anti-tumor efficacy (KRAS-G12D cell-derived xenograft models), and safety profile (whole-proteome cross-reactivity screening).\nResults: Mechano-optimized TCRs exhibited ~40-fold higher antigen sensitivity in vitro compared to conventional high-affinity TCRs, with no detectable cross-reactivity to wild-type (WT) KRAS; TCR-T cells engineered with these optimized TCRs showed superior serial tumor killing, reduced exhaustion (37% lower PD-1 expression vs. controls), and enhanced differentiation into long-lived memory phenotypes (2.2-fold higher CD62L⁺CD44⁺ cells); In KRAS-G12D CDX models, mechano-optimized TCR-T cells achieved robust tumor clearance (mean tumor volume reduction of 82% vs. 41% in controls at day 21) and displayed a more infiltrative, less exhausted T-cell phenotype; Whole-proteome cross-reactivity screening confirmed exceptional specificity, with no off-target binding to 10,000+ human proteins.\nConclusions: Our study establishes a mechano-principle-driven paradigm for rational TCR engineering. By translating fundamental insights into TCR-pMHC mechanics into a practical design framework, we generated next-generation TCRs —including TCEs, TCR mimics, and TCR-T cells —with unprecedented specificity, sensitivity, and potency. This platform offers a promising route toward safer and more effective immunotherapies for solid tumors and leukemia. Our lead TCR-T candidate is currently advancing into IND-enabling studies, alongside a complementary in vivo TCR engineering program aimed at expanding the therapeutic reach of this mechano-principled approach.", "source_company": "Zhejiang University", "source_org_type": "大学", "row_number": 608, "target_meta": "KRAS G12D", "MOA_meta": "TCR T细胞疗法"}, {"drug_name": "PYCR1 inhibitors", "company": "Chemspace LLC", "org_type": "公司", "target": "PYCR1", "modality": "inhibitor", "importance_level": "中", "total_score": 60.5, "institution_score": 50, "track_score": 75, "milestone_score": 60, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "靶点为PYCR1（脯氨酸生物合成关键酶），通过结构导向的片段晶体学筛选发现新型变构结合位点，为非经典抑制剂开发提供新路径。Chemspace作为CRO类公司非头部MNC，机构分中等；靶点在肿瘤代谢重编程领域有潜力但仍早期，赛道热度较高，整体里程碑为preclinical片段命中+变构位点发现。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6539", "id": "ElXM_5wBX1NQZOEH-LO6", "source_drug_name": "PYCR1 inhibitors", "title": "Beyond the active site: Discovery of novel PYCR1 allosteric binding sites via structure-oriented fragment crystallographic screening", "abstract_text": "Pyrroline-5-carboxylate reductase 1 (PYCR1), a member of the PYCR enzyme family, plays a pivotal role in the proline biosynthesis pathway. Enzymes involved in proline metabolism have been increasingly recognized as key regulators of cancer cell metabolic reprogramming, contributing to enhanced proliferation, survival, metastasis, and resistance to stress. Overexpression of PYCR1 has been consistently reported across multiple malignancies, including hepatocellular carcinoma, breast cancer, gastric cancer, bladder cancer, and lung cancer, as well as in fibrotic disorders. These observations highlight PYCR1 as an attractive therapeutic target for oncology drug discovery.\nDespite its therapeutic potential, PYCR1 remains an understudied target, with limited data available on active small-molecule ligands and binding site characterization. Consequently, the discovery of novel chemical probes is critical both for validating PYCR1’s role in disease pathology and for initiating structure-based drug design campaigns.\nTo this end, a fragment-based screening campaign was initiated using a focused subset of carboxylic acid-containing fragments from the Enamine fragment library. The subset was rationally designed through molecular docking of fragment-like, carboxylic acid-containing compounds from Enamine’s in-stock collection, targeting the active site of PYCR1. A total of 37 fragments were selected and screened via X-ray crystallography. This screen yielded eight fragments with confirmed binding to the PYCR1 active site, as determined by co-crystal structures. Among these, three compounds demonstrated inhibitory activity in biochemical assays, with IC₅₀ values ranging from 29 μM to 5.4 mM.\nEncouraged by these results, a follow-up screen was conducted using 22 fragment-like compounds containing bioisosteres of the carboxylic acid functional group (e.g., tetrazoles, oxadiazoles) and sulfonic acid groups, to explore alternative chemical scaffolds. This second crystallographic screen identified one additional active-site binder. Importantly, at least two previously uncharacterized allosteric binding sites were discovered, both of which showed a measurable inhibitory effect on PYCR1 enzymatic activity. These findings open promising new avenues for the development of non-classical inhibitors targeting PYCR1.", "source_company": "Chemspace LLC", "source_org_type": "公司", "row_number": 662, "target_meta": "PYCR1", "MOA_meta": "抑制剂"}, {"drug_name": "spherical nucleic acids (SNAs)", "company": "Northwestern University Feinberg School of Medicine", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "中", "total_score": 60.5, "institution_score": 35, "track_score": 85, "milestone_score": 70, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "SNAs作为纳米材料平台用于ex vivo修饰B细胞实现癌症免疫治疗的ACT新范式，靶点未明确披露但机制创新突出。机构为大学非商业实体得分较低，但纳米递送+免疫细胞工程属于热门赛道且preclinical数据强劲包括多模型疗效和机制验证。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3679", "id": "h1XM_5wBX1NQZOEH-LO6", "source_drug_name": "spherical nucleic acids (SNAs)", "title": "Expanding the ACT paradigm: B cell engineering via spherical nucleic acids for cancer immunotherapy", "abstract_text": "Adoptive cellular therapy (ACT) has revolutionized cancer immunotherapy, yet its focus remains largely on T cells. B cells, despite their potent antigen-presenting capacity and role in adaptive immunity, have been underutilized due to inefficient antigen delivery and activation. We developed an ex vivo strategy leveraging spherical nucleic acids (SNAs) to license B cells for ACT. This platform synchronizes pH-controlled co-delivery of tumor antigen peptides and TLR9 agonists into shared endosomal compartments, enabling sustained antigen presentation and robust cross-priming of tumor-specific CD8⁺ T cells, resulting in epitope spreading and durable antitumor immunity.SNA-trained B cells exhibited lymphoid homing and secreted CCL3/CCL4, establishing a CCR5-dependent chemotactic axis that recruited effector CD8⁺ T cells and cDC1, creating spatial immune hubs within tumors. Multiplex immunohistochemistry analysis revealed clustering of transferred B cells, CD8⁺ T cells, and cDC1 in draining lymph nodes, facilitating antigen handoff and reciprocal activation. Mechanistic studies confirmed that CCR5 blockade or CD8⁺ T-cell depletion abrogated efficacy. Across multiple murine and humanized tumor models, SNA-trained B cells outperformed controls, reduced metastasis, and synergized with PD-1 blockade to improve survival. Single-cell transcriptomics and BCR-seq demonstrated progression toward plasma cell differentiation, oligoclonal expansion, and IgG2 class switching.This work introduces a nanomaterial-based platform to reprogram B cells for ACT, overcoming limitations in immunologically “cold” and checkpoint-refractory tumors. SNA-trained B cells broaden the ACT paradigm beyond T cells, offering a versatile and well-tolerated strategy for durable antitumor immunity.", "source_company": "Northwestern University Feinberg School of Medicine", "source_org_type": "大学", "row_number": 742, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "RAS inhibitor", "company": "Abramson Cancer Center, University of Pennsylvania", "org_type": "医院", "target": "RAS", "modality": "inhibitor", "importance_level": "中", "total_score": 60.5, "institution_score": 40, "track_score": 95, "milestone_score": 50, "field_heat_score": 90, "bonus_score": 3, "brief_reason": "靶向活性RAS的抑制剂在小鼠模型中实现胰腺癌拦截（预防形成），机制新颖且针对KRAS驱动的胰腺癌这一高未满足需求领域。机构为学术医院而非产业公司导致机构分较低，但RAS热门赛道+胰腺癌潜力+preclinical拦截概念带来较高赛道与领域热度，总分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/12320", "id": "51XM_5wBX1NQZOEH-LO6", "source_drug_name": "RAS inhibitor", "title": "Active RAS inhibition intercepts pancreas cancer in mice", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Abramson Cancer Center, University of Pennsylvania", "source_org_type": "医院", "row_number": 814, "target_meta": "Ras", "MOA_meta": "抑制剂"}, {"drug_name": "ZF7-edited T cells", "company": "University of California San Francisco", "org_type": "大学", "target": "TNFAIP3/A20 ZF7 motif", "modality": "CAR", "importance_level": "中", "total_score": 60.5, "institution_score": 35, "track_score": 85, "milestone_score": 75, "field_heat_score": 80, "bonus_score": 4, "brief_reason": "通过base editing精准失活A20的ZF7 motif显著解除CD8 T细胞耗竭状态下degranulation抑制，提升ACT抗肿瘤效力，机制新颖且独立于细胞因子。大学背景拉低机构分，但热门细胞治疗赛道+清晰preclinical efficacy和创新机制带来较高赛道与里程碑价值。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3674", "id": "bp7ECZ0BZznHJdntvNYd", "source_drug_name": "ZF7-edited T cells", "title": "The zinc finger 7 motif of TNFAIP3/A20 enforces a critical block in exhausted CD8 T cell degranulation and represents a potent target for enhancing adoptive cellular therapies for cancer", "abstract_text": "Introduction: CD8 T cells eliminate tumors through effector cytokines (IFNgamma, TNF) and cytotoxic granule protein release (perforin, granzymes). The relative contribution of these mechanisms varies across tumor contexts, suggesting distinct modes of regulation. CD8 T cell exhaustion within the tumor microenvironment limits their cytotoxic potential and poses a major obstacle for cancer immunotherapy and adoptive cellular therapies (ACTs). While most studies of exhausted CD8 T cell (Tex) dysfunction have focused on impaired cytokine production, the regulation of perforin- and granzyme-mediated cytotoxicity, as well as the pathways governing CD8 T cell degranulation in general, remain poorly defined.\nMethods & Results: We performed a genome-wide CRISPR knockout screen in repetitively stimulated human T cells and identified the multifunctional ubiquitin-modifying enzyme tumor necrosis factor alpha-induced protein 3 (TNFAIP3, or A20) as a key suppressor of T cell persistence and cytotoxicity in the face of exhaustive stress. Using a large language model, base editor tiling screen, and tumor models in hypomorphic A20 knock-in mice, we pinpointed the zinc finger (ZF7) motif of A20 as the crucial regulator of CD8 T cell cytotoxicity. We then incorporated base-editing into standard human ACT production workflow to introduce a single inactivating missense mutation in ZF7 that significantly improved ACT efficacy in preclinical leukemia and melanoma models. Although ZF7-edited T cells produced more IFNgamma and TNF, genetic ablation experiments revealed these cytokines were dispensable for improved tumor control. Instead, through in vivo and in vitro functional assays, we revealed an underappreciated block in perforin and granzyme degranulation — rather than expression — that was relieved by ZF7 ablation. Finally, genetic epistasis analyses uncovered a surprising role for receptor-interacting serine/threonine-protein kinase 3 (RIPK3) — a canonical activator of necroptosis without a defined role in CD8 T cell effector function — as the critical orchestrator of degranulation in ZF7-deficient cells.\nConclusions: Our findings highlight an underrecognized yet critical post-translational block in Tex degranulation, regulated independently of cytokine production, and relieved upon targeted disruption of the ZF7 motif in a RIPK3-dependent manner. These results demonstrate that selective targeting of central suppressors such as A20 can not only reverse CD8 T cell exhaustion but also engage alternative signaling programs to unleash cytotoxicity. These insights address critical gaps in our understanding of the biological networks that restrain perforin-dependent cytotoxicity in Tex and provide a foundation for enhancing the potency and durability of ACTs.", "source_company": "University of California San Francisco", "source_org_type": "大学", "row_number": 863, "target_meta": "TNFAIP3", "MOA_meta": "其他"}, {"drug_name": "ALK-directed CAR T cells", "company": "Children's Hospital of Philadelphia", "org_type": "医院", "target": "ALK", "modality": "CAR", "importance_level": "中", "total_score": 60.5, "institution_score": 35, "track_score": 85, "milestone_score": 75, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "靶向ALK的CAR-T细胞疗法，ALK为儿童神经母细胞瘤等实体瘤的肿瘤特异性靶点，采用优化CD28构型提升低表达抗原敏感性。机构为医院研究性质得分较低，但CAR赛道及实体瘤应用热度高，前临床数据展示肿瘤清除及持久应答获较强里程碑支持。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5327", "id": "L1XM_5wBX1NQZOEH-LS6", "source_drug_name": "ALK-directed CAR T cells", "title": "Harnessing an optimized cellular therapy platform for ALK-expressing pediatric and adult solid tumors", "abstract_text": "Background: Patients with high-risk neuroblastoma and fusion-positive rhabdomyosarcoma face poor survival outcomes and significant treatment-related co-morbidities, necessitating precision targeted therapies. The Anaplastic Lymphoma Kinase (ALK) is a tumor-restricted oncofetal protein highly expressed in these pediatric tumors and select adult malignancies.\nMethods: We developed 56 ALK-directed chimeric antigen receptor (CAR) T cell architectures constructed from a library of 11 highly active and specific scFvs produced by Retained DisplayTM screen against ALK antigen encompassing the extracellular domain. CAR architectures included varying scFv orientations, CD8 or CD28 transmembrane domains, and CD28 or 41BB co-stimulatory domains. We systematically screened these CAR constructs with multiple T cell donors against neuroblastoma cell lines and spheroid models with a range of ALK surface expression: NB-1 (high), IMR-32 (moderate), NGP (moderate), and CHP134 (low). Lead candidates were tested with two different T cell donors in vivo against NB-1 (ALK high) and Felix (ALK moderate) xenograft models with 10x106 CAR+ cells. Peripheral blood was analyzed weekly for CAR+ cells.\nResults: Three ALK-directed scFvs significantly increased T cell activation (CD69) and degranulation (CD107a, p<0.01) with elevated IL-2, IFNγ and granzyme B production (p<0.05) in an ALK-dependent manner after 6 and 24 hours of co-culture. The lead constructs exhibited potent cytotoxicity with tumor clearance in both 2D and spheroid co-cultures confirmed by live imaging of GFP-labeled cell lines and Caspase-3/7 red dye assay across effector-to-target cell ratios of 4:1 to 1:4. Antigen specificity was validated by the absence of activation, cytokine production or cytotoxicity against ALK knockout NGP cells. In xenograft models, these CAR T cell constructs achieved complete and durable tumor regression in NB-1 and transient-to-durable responses in Felix tumors. Peak circulating CAR+ T cells occurred at day 14 in NB-1 and day 7 in Felix models with enrichment of central-memory phenotypes (CD62L+ and IL7Rα+, low CD45RA and LAG3). Constructs incorporating CD28 transmembrane and costimulatory domains conferred enhanced activation, cytokine release and efficacy at moderate and low ALK density.\nConclusions: These findings validate ALK as a selective cellular immunotherapy target and highlight novel CAR architectures integrating CD28 transmembrane and costimulatory domains to achieve high antigen sensitivity and sustained functional persistence. These optimized CAR designs enable variable ALK recognition and may improve clearance of minimal residual disease. Next-generation constructs incorporating FOXO1 overexpression and NFAT-inducible IL-15 expression via bicistronic vectors will further address resistance mechanisms within the immunosuppressive solid tumor microenvironment.", "source_company": "Children's Hospital of Philadelphia", "source_org_type": "医院", "row_number": 865, "target_meta": "ALK", "MOA_meta": "其他"}, {"drug_name": "MSLN/AQP3 lung-SAFE CAR-T cells", "company": "Tongji Hospital, Tongji Medical College, Huazhong University of Science and Technology", "org_type": "医院", "target": "MSLN", "modality": "CAR", "importance_level": "中", "total_score": 60.5, "institution_score": 35, "track_score": 85, "milestone_score": 75, "field_heat_score": 80, "bonus_score": 8, "brief_reason": "药物为针对MSLN的NOT逻辑门控lung-SAFE CAR-T，通过AQP3抑制信号避免肺部脱靶毒性，保留对卵巢癌的强效杀伤。机构为国内三甲医院非头部药企导致机构分较低，但CAR-T固瘤安全优化+单细胞指导新机制创新在热门赛道中具较高潜力。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5206", "id": "c57ECZ0BZznHJdntvNYd", "source_drug_name": "MSLN/AQP3 lung-SAFE CAR-T cells", "title": "AQP3 NOT gating mitigates lethal on-target off-tumor pulmonary toxicity of MSLN-directed CAR-T cells in ovarian cancer", "abstract_text": "Background: Mesothelin (MSLN) is overexpressed across multiple solid tumors and represents a promising therapeutic target. However, MSLN-directed chimeric antigen receptor (CAR)-T cells have been associated with lethal pulmonary on-target off-tumor toxicity. Here, we implemented a “NOT” logic-gating strategy to engineer dual-input MSLN/AQP3 lung-Specific Attenuated Functionally Engineered (lung-SAFE) CAR-T cells that retained potent antitumor activity against ovarian cancer while preventing fatal pulmonary toxicity.\nMethods: A phase I trial (NCT05141253) was ongoing to evaluate the safety of MSLN-directed CAR-T cells in patients with solid tumors. Human MSLN (hMSLN) knock-in NCG mice bearing SKOV3 xenografts received intravenous MSLN-CAR-T cells and were longitudinally monitored for signs of toxicity. Major organs and peripheral blood were collected at moribund stages. MSLN expression, CAR-T cell infiltration, and lung injury were analyzed. Integrated analyses of in-house single-cell ovarian cancer datasets and publicly available single-cell lung datasets were performed to identify candidate inhibitory targets, which were subsequently validated in vitro and in vivo. CAR-T cell activation and cytotoxicity were assessed using flow cytometry, cell lysis assays, and cytokine quantification in co-culture supernatants.\nResults: In the phase I trial, two patients with ovarian cancer experienced fatal pulmonary toxicity following MSLN-CAR-T cell infusion. To elucidate the underlying mechanism, we generated hMSLN knock-in NCG mice, which faithfully recapitulated the lethal pulmonary injury observed in patients. This toxicity was mediated by MSLN expression on alveolar cells and CAR-T cell-driven immunopathology. To overcome this limitation, we integrated single-cell transcriptomic analyses of ovarian cancer and healthy lung tissues to identify molecules selectively enriched in alveolar cells but minimally expressed in ovarian cancer cells. Cross-validation in cell lines, organoids, and human tissue specimens identified AQP3 as the most selective target. We then engineered a dual-input MSLN/AQP3 lung-SAFE CAR-T cells, wherein AQP3 delivered an inhibitory signal to suppress MSLN-CAR-T cell activation in the lung. The resulting lung-SAFE CAR-T cells maintained potent cytotoxicity against MSLN+ ovarian cancer cells while sparing AQP3+ alveolar cells in vitro.\nConclusions: This study established hMSLN knock-in NCG mice as a robust preclinical platform to evaluate the safety of MSLN-targeted CAR-T cells, identified AQP3 as a key molecular switch to mitigate their pulmonary toxicity in ovarian cancer, and introduced a generalizable framework that integrated single-cell transcriptomics with “NOT” logic-gating design for precision control of organ-specific CAR-T cell toxicity, advancing the safer translation of CAR-T cell therapies for solid tumors.", "source_company": "Tongji Hospital, Tongji Medical College, Huazhong University of Science and Technology\nHuazhong University of Science and Technology Tongji Hospital", "source_org_type": "医院", "row_number": 905, "target_meta": "MSLN", "MOA_meta": "其他"}, {"drug_name": "Δ133p53α", "company": "National Cancer Institute, National Institutes of Health", "org_type": "研究机构", "target": "未披露", "modality": "other", "importance_level": "中", "total_score": 60.5, "institution_score": 45, "track_score": 75, "milestone_score": 65, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "Δ133p53α为p53截短异构体，通过抑制衰老和炎症展现抗早衰潜力，但非传统药物靶点而是内源性蛋白干预。机构为NIH下属国家癌症研究所非商业化研发，赛道涉及衰老干预有较高科学热度，动物模型显示10%寿命延长具一定里程碑意义。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/2423", "id": "PJ7M_5wBZznHJdnt_W3O", "source_drug_name": "Δ133p53α", "title": "Senescence-inhibitory Δ133p53α mitigates accelerated ageing in mice", "abstract_text": "Hutchinson-Gilford progeria syndrome (HGPS), a premature aging disorder caused by a de novo LMNA G608G mutation, is characterized by the accumulation of DNA damage and persistent inflammation, which drive accelerated aging and lead to severe clinical manifestations, including skin atrophy, alopecia, and progressive deterioration of the aortic wall due to loss of vascular smooth muscle cells, resulting in severely shortened lifespan. Mouse models of HGPS recapitulate these pathological aging phenotypes, including cardiovascular defects, increased cellular senescence, DNA damage accumulation, systemic inflammation, and shortened lifespan.The human p53 isoform Δ133p53α, which lacks the N-terminal 133 amino acids, is a naturally occurring truncated variant with distinct biological functions. In HGPS patient-derived fibroblasts, Δ133p53α suppresses cellular senescence, reduces pro-inflammatory IL-6 production, limits DNA-damage accumulation, and extends replicative lifespan. These findings suggest that Δ133p53α selectively attenuates p53-mediated cell-cycle arrest and senescence while preserving DNA-repair functions.Here, in a heterozygous HGPS mouse model, we show that transgenic expression of Δ133p53α reproduces these in vitro-observed effects across multiple organs in vivo and extends median lifespan by approximately 10% (387 vs. 358 days, P = 0.0235). In the aorta and skin, Δ133p53α mitigates progeria-associated pathological changes and preserves tissue integrity. Δ133p53α also mitigates spinal kyphosis characteristic of the HGPS mouse phenotype. RNA-sequencing analysis suggests that Δ133p53α promotes mitochondrial function and metabolic fitness. The effects of Δ133p53α in naturally aging mice are under investigation. Our human expression database analysis shows an age-associated downregulation of Δ133p53α in multiple human tissues, including aorta and skin.This study suggests not only a Δ133p53α-based therapeutic approach for HGPS but also broader interventions for preventing or delaying aging.", "source_company": "National Cancer Institute, National Institutes of Health", "source_org_type": "研究机构", "row_number": 990, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "Flower signaling inhibitor", "company": "VCU Massey Comprehensive Cancer Center", "org_type": "医院", "target": "Flower (hFWE, Flower-Lose isoform)", "modality": "monoclonal antibody", "importance_level": "中", "total_score": 60.5, "institution_score": 35, "track_score": 85, "milestone_score": 75, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "靶向Flower基因（hFWE）的Flower-Lose异构体，通过单抗阻断其fitness surveillance机制，逆转肿瘤微环境T细胞耗竭并显著增强ICI疗效，针对多种免疫冷肿瘤显示泛癌潜力。机构为学术医院得分较低，但新型机制+preclinical强效数据（T细胞密度5-7倍、肿瘤抑制>90%、生存显著改善）使赛道与里程碑热度较高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9469", "id": "BJ7M_5wBZznHJdnt_W7O", "source_drug_name": "Flower signaling inhibitor", "title": "Targeting fitness surveillance restores T-cell immunity and sensitizes solid tumors to immune checkpoint inhibitors", "abstract_text": "Immune checkpoint inhibitors (ICIs) fail in most solid tumors despite their transformative success in a minority of patients. Here, using integrated human tumor profiling and humanized patient-derived xenograft (PDX) models, we identify Flower-mediated fitness elimination as a dominant, conserved mechanism of T-cell attrition that limits ICI efficacy across epithelial cancers. Stromal compartments in high-grade serous ovarian cancer, non-small-cell lung cancer, colorectal cancer, hepatocellular carcinoma, and pancreatic ductal adenocarcinoma exhibit high Flower-Lose expressioncoupled to severe CD8⁺ T-cell exclusion. Tumor-infiltrating T-cells themselves acquire a “loser” state marked by elevated Flower-Lose, rendering them vulnerable to competitive elimination by the stromal niche.\nAcross five orthotopic humanized PDX tumor types and three independent cohorts, ICIs alone produced minimal T-cell restoration, persistent metastatic dissemination, and negligible survival benefit (e.g., median ≈42 days). In contrast, pharmacologic blockade of Flower signaling increased intratumoral T-cell density by 5-7-fold (MixedLM P < 10⁻¹⁵), reduced metastatic burden by 54-75%, suppressed tumor growth by >90%, and produced durable survival benefit across all models, with median survival not reached and strong meta-analytic significance (Z = 10.56, P < 10⁻²⁵).\nTogether, these findings reveal Flower-mediated fitness surveillance as a pan-cancer, tissue-level barrier to immunotherapy and establish Flower blockade as a universally effective strategy to restore T-cell persistence and unlock durable ICI responses across historically immune-cold solid tumors.", "source_company": "VCU Massey Comprehensive Cancer Center", "source_org_type": "医院", "row_number": 1133, "target_meta": "not available", "MOA_meta": "单抗"}, {"drug_name": "Organoid Interacting Lymphocytes", "company": "Wake Forest University School of Medicine", "org_type": "大学", "target": "未披露", "modality": "CAR", "importance_level": "中", "total_score": 60.5, "institution_score": 35, "track_score": 85, "milestone_score": 75, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "OILs为基于患者自体器官芯片平台驯化的肿瘤特异性细胞毒性淋巴细胞，属于个性化细胞治疗，靶点未明确披露。大学机构得分较低，但细胞治疗赛道热度高、前临床平台显示优异浸润/杀伤/抑瘤效果且具转化潜力，故综合重要性为中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1425", "id": "D57M_5wBZznHJdnt_W7O", "source_drug_name": "Organoid Interacting Lymphocytes", "title": "Overcoming pancreatic ductal adenocarcinoma immunoresistance: Microfluidic-primed organoid interacting lymphocytes demonstrate superior infiltration, cytotoxicity, and tumor suppression in patient-derived models", "abstract_text": "Background: Pancreatic ductal adenocarcinoma (PDAC) remains refractory to immunotherapy due to its immunosuppressive tumor microenvironment (TME), characterized by dense desmoplasia, immune exclusion, and T cell exhaustion. With 5-year survival <13%, novel strategies are urgently needed. We developed a platform to generate and evaluate tumor-specific cytotoxic lymphocytes using immunocompetent patient-derived organoids (PTOs) that recapitulate the PDAC TME.\nMethods: Immunocompetent PTOs (iPTOs) were established by co-culturing resected PDAC tissue with autologous tumor-draining lymph node cells. Autologous PBMCs were primed via microfluidic tumor-on-a-chip circulation, generating Organoid Interacting Lymphocytes (OILs). OILs were expanded for 14 days and co-cultured with patient-matched PTOs at 5× and 10× effector:target ratios. Tumor-immune dynamics were quantified using high-resolution time-lapse microscopy with automated single-cell tracking, flow cytometry (CD45, CK19, viability), and longitudinal tumor area measurements over 96 hours.\nResults: Flow cytometry demonstrated robust immune infiltration, with CD45+ cells comprising 26% of OIL-treated cultures versus 0.5% in tumor-only controls. OILs induced 93% tumor cell death compared to 68% with unstimulated PBMCs. Quantitative tracking revealed OILs migrated 6.1 pixels closer to tumor cells versus 0.6 pixels for PBMCs over 24 hours (P<0.05). At 27 hours, OIL-treated organoids exhibited consistent tumor area reduction (-2% to -13%), while PBMC-treated wells showed variable responses including tumor expansion (+7%). Longitudinal analysis confirmed sustained suppression with live OILs, whereas heat-killed OILs permitted 15-fold tumor expansion, demonstrating viability-dependent cytotoxicity. Time-lapse microscopy captured direct killing events, immune synapse formation, and tumor clustering consistent with immune evasion. These findings replicate observations in appendiceal and mesothelioma models where OILs outperformed tumor-infiltrating lymphocytes.\nConclusions: OILs represent a potent, patient-specific adaptive cell therapy capable of overcoming PDAC's immunosuppressive TME. This immunocompetent organoid platform enables quantitative real-time assessment of personalized immunotherapies and supports clinical translation of OIL-based therapies for pancreatic cancer.", "source_company": "Wake Forest University School of Medicine", "source_org_type": "大学", "row_number": 1138, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "E4ORF-1 engineered NK cells", "company": "UT MD Anderson Cancer Center", "org_type": "医院", "target": "未披露", "modality": "CAR", "importance_level": "中", "total_score": 60.5, "institution_score": 35, "track_score": 85, "milestone_score": 75, "field_heat_score": 80, "bonus_score": 4, "brief_reason": "通过腺病毒E4ORF-1基因工程显著提升NK细胞代谢灵活性，克服实体瘤营养限制微环境，实现代谢重编程增强CAR-NK抗肿瘤活性。机构为顶级肿瘤中心但非商业药企拉低分数，热门细胞治疗+代谢工程赛道及较强的preclinical数据支撑整体中高潜力。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9401", "id": "UJ7M_5wBZznHJdnt_W7P", "source_drug_name": "E4ORF-1 engineered NK cells", "title": "Metabolically supercharged NK cells engineered with adenoviral E4ORF-1", "abstract_text": "Background: Chimeric antigen receptor (CAR) T and natural killer (NK) cells have achieved success in hematologic malignancies but show limited efficacy in solid tumors. A major barrier is the metabolically hostile solid tumor microenvironment (TME), where hypoxia, acidosis, and nutrient deprivation impair immune cell fitness, cytotoxicity, and persistence. Current metabolic engineering strategies that enhance single nutrient uptake or target one metabolic pathway provide only partial benefit and remain vulnerable to tumor metabolic plasticity. A critical unmet need is the development of immune cells with metabolic flexibility rather than single-pathway dependence. To address this, we explored a strategy inspired by viral metabolic rewiring. During adenoviral infection, the viral protein E4ORF-1 activates PI3K-AKT signaling, stabilizes MYC, augments nutrient uptake, and enhances glycolysis, oxidative phosphorylation (OXPHOS), and fatty acid oxidation (FAO). We hypothesized that engineering E4ORF-1 into NK cells would generate a viral-like metabolic state capable of withstanding nutrient restriction in solid tumors.\nMethods: Metabolic characterization included mitochondrial mass and membrane potential, Seahorse assays, and SCENITH. CAR-NK cells were cocultured with solid tumor cell lines, and cytotoxicity was quantified using xCelligence and IncuCyte platforms. In vivo efficacy was tested in xenograft models of hematologic (MOLM14) and solid tumors (SKOV3). Mechanistic studies incorporated bulk RNAseq, CyTOF profiling, and CRISPR-Cas9 knockout of AMPK.\nResults: E4ORF-1 expression significantly enhanced NK cell antitumor function across tumor models and sustained cytotoxicity and metabolic fitness under glucose-, glutamine-, or lipid-limited conditions. Western blotting confirmed coordinated upregulation of nutrient transporters and metabolic enzymes across glycolysis, OXPHOS, and FAO. E4ORF-1 NK cells also maintained a cytotoxic advantage under targeted metabolic inhibition; despite blockade of glycolysis, OXPHOS, FAO, or glutamine metabolism, they consistently demonstrated superior tumor killing, underscoring enhanced metabolic adaptability. Transcriptomic profiling showed preserved cytokine signaling and metabolic signatures even under nutrient restriction or after tumor challenge. Mechanistic studies identified AMPK as a central metabolic integrator required for the E4ORF-1 phenotype, as CRISPR deletion of AMPK abrogated metabolic and functional advantages. Incorporation of E4ORF-1 into CAR-NK cells improved tumor control and survival in vivo.\nConclusion: E4ORF-1 enhances NK cell metabolic flexibility, enabling sustained antitumor activity and improving therapeutic potential for solid tumors. These findings establish viral gene-mediated metabolic rewiring as a promising platform to strengthen CAR-NK cell fitness and overcome nutrient competition in the TME.", "source_company": "UT MD Anderson Cancer Center", "source_org_type": "医院", "row_number": 1181, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "PLB-015", "company": "Primelink Biotherapeutics", "org_type": "公司", "target": "HER2", "modality": "ADC", "importance_level": "中", "total_score": 60.5, "institution_score": 55, "track_score": 90, "milestone_score": 40, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "PLB-015为新型anti-HER2双payload ADC，靶向HER2阳性实体瘤，具有创新的双负载设计；公司为2021年成立的中国新兴ADC biotech，平台技术先进但整体仍处preclinical阶段，AACR poster展示体现早期进展。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11426", "id": "T1XM_5wBX1NQZOEH-LS6", "source_drug_name": "PLB-015", "title": "PLB-015 a novel anti-HER2 dual payload ADC for the treatment of HER2 positive solid tumors", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Primelink Biotherapeutics", "source_org_type": "公司", "row_number": 1284, "target_meta": "HER2", "MOA_meta": "抗体偶联药物"}, {"drug_name": "Crept-618", "company": "Tsinghua University", "org_type": "大学", "target": "CREPT", "modality": "GalNAc-siRNA", "importance_level": "中", "total_score": 60.3, "institution_score": 35, "track_score": 82, "milestone_score": 78, "field_heat_score": 85, "bonus_score": 4, "brief_reason": "Crept-618为首创GalNAc-siRNA靶向CREPT，通过沉默CREPT恢复CCL5表达转化冷肿瘤为热肿瘤并显著协同anti-PD-1产生78.3%肿瘤回缩。大学背景拉低机构分，但新型siRNA+热门免疫协同机制+强效体内数据+IND准备使其赛道与里程碑评分较高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9423", "id": "Pp7M_5wBZznHJdnt_W3O", "source_drug_name": "anti-PD-1", "title": "Crept-618: First GalNAc-siRNA targeting CREPT reverses HCC immune evasion and synergizes with anti-PD-1", "abstract_text": "Purpose: Immune checkpoint inhibitors (ICIs) achieve responses in only approximately ~20% of hepatocellular carcinoma (HCC) patients due to immunologically “cold” tumors characterized by poor T-cell infiltration. We identify CREPT—overexpressed in HCC and linked to worse survival (HR=2.722, P=0.0018) and ICI non-response (higher expression in non-responders; GSE215011, P<0.01)—as a dual driver of tumor proliferation and immune silencing. We present CREPT-618, the first GalNAc-conjugated siRNA targeting CREPT.\nExperimental Procedures: CREPT expression was analyzed in TCGA, GEO, CPTAC databases and validated by immunohistochemistry in a 104-patient HCC tissue microarray. Functional roles were tested via CREPT knockdown in HCC cell lines (LM3, Huh7, Hep3B and Hepa1-6) using proliferation, migration, and invasion assays. In vivo efficacy was assessed in humanized orthotopic implantation mouse models with or without anti-PD-1 combination. The underlying mechanism was studied using RNA-seq, ATAC-seq, ChIP-seq, and scRNA-seq. CREPT-618 was tested for potency (no transfection), specificity, PK, biodistribution (Cy5/LC-MS), and GLP toxicology in mice, rats, and monkeys.\nNew, Unpublished Data: CREPT recruits the SIN3A-HDAC1/2 complex to the CCL5 promoter, leading to chromatin compaction (ATAC-seq) and silencing IFN-γ/IRF1-induced CCL5 transcription (ChIP-seq). CREPT loss increased CCL5 secretion (3.7-fold, P<0.001), driving CD8+ T/NK infiltration (2.8-fold, P<0.01; scRNA-seq)—prevented by CCR5 blockade, confirming CCL5 dependence. CREPT-618 achieved potent, specific silencing (IC₅₀ 0.046-1.628 nM; RNA-seq/PCA validated) with liver-focused PK (Cmax ~200 μg/g, T½ ~70 h). In orthotopic HCC, monotherapy modestly suppressed growth across 3 batches (IHC target engagement confirmed), while combination with anti-PD-1 drove synergistic 78.3% tumor regression (P<0.001) and a 5.1-fold increase in cytotoxic CD8+ T cells. CREPT-618 was well-tolerated up to 100 mg/kg (rodents) and 30 mg/kg (monkeys).\nConclusion: CREPT drives HCC growth and immune evasion by repressing CCL5, blocking T-cell recruitment via the CCL5-CCR5 axis. CREPT-618—the first siRNA targeting CREPT—silences this oncogenic hub, restores CCL5 signaling, converts “cold” tumors to “hot”, and synergizes with anti-PD-1. These preclinical data will enable a first-in-human trial; preliminary human safety and CREPT knockdown data will be presented at AACR.", "source_company": "Tsinghua University", "source_org_type": "大学", "row_number": 992, "target_meta": "CRIPT", "MOA_meta": "其他"}, {"drug_name": "anti-PD1 immunotherapy", "company": "German Cancer Consortium (DKTK)", "org_type": "研究机构", "target": "PD-1", "modality": "inhibitor", "importance_level": "中", "total_score": 60, "institution_score": 35, "track_score": 85, "milestone_score": 75, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "药物为anti-PD1免疫治疗（靶向PD-1），属于肿瘤免疫治疗热门赛道；由德国癌症联盟研究机构开展，在乳腺癌模型中联合cabozantinib+多柔比星实现完全肿瘤消退，显示较强组合协同潜力，但机构非商业化药企导致总体评分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4911", "id": "b1XM_5wBX1NQZOEH-LG5", "source_drug_name": "anti-PD1 immunotherapy", "title": "Spatial proteomics reveals vasculature and immune modulation for overcoming doxorubicin resistance in breast cancer", "abstract_text": "Therapeutic resistance hinders the efficacy of single-agent cancer treatments, often mediated by the tumor microenvironment. Significant endothelial cell enrichment following local doxorubicin treatment has been proposed as a resistance mechanism in breast cancer. Here, we apply the tumor vasculature normalization principle using an anti-angiogenic drug combination delivered locally using the high-throughput multiplex implantable microdevice assay in mouse models of breast cancer. Spatial single-cell proteomic profiling paired with unsupervised learning methods confirmed doxorubicin-mediated pro-angiogenic changes, including pericyte detachment and sprouting angiogenesis. A combination with cabozantinib depleted endothelial cells and increased tumor antigenicity by inducing immunogenic cell death with recruitment of leukocytes including neutrophils, and T cells. Leveraging this immune modulatory activity, we tested a systemic triple combination with anti-PD1 immunotherapy, which led to a significant and complete tumor regression. Our study demonstrates a rational drug combination that improves doxorubicin efficacy to overcome microenvironment-driven resistance for long-term breast cancer control.", "source_company": "German Cancer Consortium (DKTK)", "source_org_type": "研究机构", "row_number": 15, "target_meta": "PD1", "MOA_meta": "抑制剂"}, {"drug_name": "Vivo-T", "company": "Syenex", "org_type": "研究机构", "target": "CD19", "modality": "CAR", "importance_level": "中", "total_score": 60, "institution_score": 35, "track_score": 85, "milestone_score": 65, "field_heat_score": 80, "bonus_score": 4, "brief_reason": "Vivo-T为T细胞特异性慢病毒载体平台，实现体内直接递送anti-CD19 CAR，靶向CD19，属于热门的CAR赛道且解决传统CAR-T制造痛点。研究机构背景导致机构分较低，但in vivo高效转导、快速扩增及强抗肿瘤活性显示较好preclinical强度，综合热度较高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4567", "id": "YVXM_5wBX1NQZOEH-LG5", "source_drug_name": "Vivo-T", "title": "In vivo lentiviral CAR-T gene delivery demonstrates high specificity and potent anti-tumor activity in a humanized B cell lymphoma model", "abstract_text": "Introduction: Chimeric Antigen Receptor T (CAR-T) cell therapies have revolutionized treatment for hematologic malignancies, particularly B cell cancers, and show promise in autoimmune diseases and solid tumors. Despite this success, the conventional approach to CAR-T manufacturing presents several limitations: it requires leukapheresis, PBMC isolation, ex vivo genetic modification and expansion, and reinfusion back into the patient. These steps are time-consuming, costly, and logistically complex, limiting scalability and patient accessibility. Furthermore, current CAR-T therapies have shown limited efficacy against solid tumors due to poor trafficking, immunosuppressive microenvironments, and antigen heterogeneity.\nMethods: To improve the cost-inefficient and time-consuming challenges of the standard CAR-T therapy, Syenex developed Vivo-T, a novel T cell-specific lentiviral vector (LVV) platform enabling in vivo delivery of CAR constructs, eliminating the need for ex vivo manipulation and personalized CAR-T manufacturing. This system was evaluated in JAX PBMC-humanized B cell lymphoma mouse model. NSG-MHC I/II double knockout mice were irradiated and injected intravenously with 2.5×105 Raji-Luc cells. Five days later, mice were engrafted with 1×10⁷ human PBMCs. Between 4-24 hours post-engraftment, mice received intravenous doses of T cell-targeted LVVs encoding anti-CD19 CARs. Tumor burden was monitored via IVIS imaging for 3 weeks. Toxicity was assessed through body weight, clinical observations, and serum cytokine analysis. CAR-T engraftment and expansion were evaluated by flow cytometry of peripheral blood.\nResults: In vivo delivery of the CAR construct resulted in efficient T cell transduction, with rapid and robust CAR-T expansion surpassing that of ex vivo-engineered CAR-T control. Notably, significant anti-tumor activity was observed as early as 7 days post-LVV administration. Initial signs of toxicity were primarily attributed to high viral titers; however, these effects were mitigated by reducing the viral load, without compromising the antitumor efficacy of the treatment. These findings validate the efficacy of the in vivo CAR-T system and support its potential for clinical translation.\nConclusion: The Vivo-T system represents a transformative approach to CAR-T therapy by simplifying manufacturing, reducing costs, and enabling scalable, off-the-shelf immunotherapy.", "source_company": "The Jackson Laboratory-West", "source_org_type": "研究机构", "row_number": 381, "target_meta": "CD19", "MOA_meta": "其他"}, {"drug_name": "AR–p300 DALTAC-1", "company": "University of Michigan", "org_type": "大学", "target": "AR-p300 interaction", "modality": "other", "importance_level": "中", "total_score": 60, "institution_score": 35, "track_score": 85, "milestone_score": 75, "field_heat_score": 80, "bonus_score": 6, "brief_reason": "AR–p300 DALTAC-1为首创DALTAC类化合物，通过重塑AR与p300的天然域间相互作用实现超级抑制，机制新颖且显示出显著的谱系选择性和前列腺癌模型中肿瘤消退。大学机构得分较低，但热门新模态+创新机制+强preclinical数据使综合潜力达中高水平。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8576", "id": "rFXM_5wBX1NQZOEH-LG6", "source_drug_name": "AR–p300 DALTAC-1", "title": "Native domain-interaction rewiring collapses the AR neo-enhanceosome in prostate cancer", "abstract_text": "The androgen receptor (AR) signaling axis remains active in metastatic castration-resistant prostate cancer (mCRPC) through adaptive mechanisms that sustain oncogenic transcriptional programs despite androgen deprivation. AR cooperates with the histone acetyltransferase p300 and other cofactors to assemble cancer-specific “neo-enhanceosomes” via highly organized domain–domain interactions that drive oncogenic gene expression. Here, we introduce a new class of chemical-induced proximity compounds, termed Domain-ALTeration Chimeras (DALTACs), which represent a distinct modality designed to rewire endogenous protein complexes by altering native domain interactions rather than degrading or inhibiting individual proteins. Our first-in-class compound, AR–p300 DALTAC-1, enforces proximity between the AR ligand-binding domain and the p300 bromodomain, thereby miswiring their native architecture and locking the complex in a non-productive configuration. This domain reconfiguration elicits a “super-inhibitory” effect that suppresses AR target gene transcription and cell proliferation more potently than concurrent inhibition of AR and p300. Mechanistically, DALTAC-1 reprograms the substrate spectrum of p300, diminishing histone H2B N-terminal acetylation (H2BNTac) and triggering the collapse of the oncogenic enhancer network. Strikingly, DALTAC-1 displays remarkable lineage selectivity, exerting potent activity in AR-driven prostate cancer cells and organoids while sparing AR-negative or non-prostate lineage tissues. In multiple prostate cancer models, DALTAC-1 exhibits robust antitumor efficacy and tumor regression with favorable tolerability. Collectively, this study establishes the DALTAC modality as a new therapeutic concept that manipulates protein complex topology to reprogram cellular function, offering a versatile and generalizable strategy to rewire diverse transcriptional, epigenetic, and signaling complexes across different cancer types. Importantly, the exquisite lineage selectivity of DALTAC-1 minimizes effects on normal tissues, underscoring its strong clinical translational potential with a low likelihood of safety concerns.", "source_company": "University of Michigan", "source_org_type": "大学", "row_number": 435, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "ANGel", "company": "Oncolab Co., Ltd.", "org_type": "公司", "target": "未披露", "modality": "other", "importance_level": "中", "total_score": 60, "institution_score": 45, "track_score": 75, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "ANGel为抗体偶联微凝胶递送平台，主要递送PD-1/PD-L1轴及共刺激通路mAb组合，实现局部缓释免疫治疗，未明确特定靶点。机构为2024年成立的韩国早期biotech，得分中等；赛道为创新递送+组合免疫治疗热度较高，临床前TNBC模型显著优于对照组合且PFS大幅延长，具有较好里程碑价值。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6402", "id": "oVXM_5wBX1NQZOEH-LS6", "source_drug_name": "ANGel", "title": "Subcutaneous ANtibody-conjugated microGel platform enabling combination immunotherapy for refractory solid tumors", "abstract_text": "Background: Drug delivery systems (DDSs) are increasingly utilized to enhance the precision and durability of biologics in oncology. However, current cancer immunotherapies show limited efficacy in solid tumors due to profoundly immunosuppressive tumor microenvironments, underscoring the need for innovative delivery platforms. We developed the ANtibody-conjugated microGel (ANGel), a deformable hydrogel-based submicron particle engineered to deliver combination monoclonal antibodies (mAbs) targeting both the PD-1/PD-L1 axis and co-stimulatory pathways.\nMethods: ANGel formulations were generated by surface affinity loading of multiple mAb types. In vitro studies assessed therapeutic synergy between two anti-PD-1/PD-L1 mAbs and two co-stimulatory mAbs when formulated with ANGel. Lead combinations were evaluated in vivo using triple-negative breast cancer (TNBC) mouse models. Subcutaneous administration was performed at peritumoral sites to assess local delivery, antitumor activity, and survival. Dose sensitivity and formulation parameters were fine-tuned to identify optimal therapeutic regimens.\nResults: ANGel significantly enhanced in vitro synergy between PD-1/PD-L1-targeting and co-stimulatory mAbs compared with free-antibody mixtures. In TNBC models, subcutaneous peritumoral delivery of combination ANGel (dANGel) formulations produced marked tumor-growth delay relative to free-combination mAbs, including combinations with hyaluronidase. Antitumor efficacy of dANGel formulations demonstrated strong dose-dependent and regimen-dependent sensitivity, enabling optimization for maximal therapeutic output. Notably, dANGel treatment extended progression-free survival to 204 days, compared with 23 days achieved by anti-PD-L1 plus anti-CTLA-4 mAbs formulated with hyaluronidase.\nConclusions: These results demonstrate ANGel as a potent local delivery platform capable of overcoming key barriers to solid-tumor immunotherapy. By enabling subcutaneous peritumoral administration of synergistic mAb combinations, ANGel provides a novel therapeutic strategy with the potential to substantially improve outcomes in refractory solid tumors. Preclinical findings support dANGel as a strong candidate for clinical translation.", "source_company": "Oncolab Co., Ltd.", "source_org_type": "公司", "row_number": 946, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "pan-RAF inhibitor", "company": "The Tisch Cancer Institute, Icahn School of Medicine at Mount Sinai", "org_type": "研究机构", "target": "RAF", "modality": "inhibitor", "importance_level": "中", "total_score": 59.5, "institution_score": 35, "track_score": 75, "milestone_score": 70, "field_heat_score": 80, "bonus_score": 8, "brief_reason": "药物为pan-RAF抑制剂，联合RAF/MEK glue(avutometinib)机制创新，通过空间捕获机制实现RAS突变肿瘤选择性更强MAPK抑制并驱动肿瘤明显消退。新机制+肿瘤选择性提升为亮点，但研发来自学术研究机构而非产业公司。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3469", "id": "VFXM_5wBX1NQZOEH-LK6", "source_drug_name": "pan-RAF inhibitor", "title": "A spatial-trapping mechanism of RAF by RAF/MEK glue enables full-dose combination with a pan-RAF inhibitor and drives potent, RAS-mutant tumor-selective MAPK and growth inhibition", "abstract_text": "The therapeutic benefits of MAPK pathway inhibitors depend on achieving more potent pathway inhibition in tumors over normal tissues, maintaining a broad therapeutic index. In BRAF-mutant cancers, selective BRAF inhibitors (BRAFi) achieve this balance, and their combination with MEK inhibitors (MEKi) at full doses resulted in significant clinical benefit. In contrast, next-generation Type 2 dimeric RAF, also known as pan-RAF inhibitors (pan-RAFi), which target wild-type BRAF and CRAF and demonstrate single-agent activity in RAS-mutant (RAS-MUT) tumors, have failed to achieve comparable therapeutic impact in combination with MEKi, owing to toxicity-driven dose reductions that constrain clinical efficacy. In preclinical and clinical studies, these combinations have reached a therapeutic ceiling, yielding predominantly stable disease and only rare tumor regressions. We show that dose-limiting toxicity in pan-RAFi + MEKi combinations stems from relief of negative feedback by MEK inhibition, which amplifies RAF activation and pan-RAFi engagement in normal tissues, oversuppressing MAPK signaling and limiting the therapeutic index. RAF/MEK glues constitute a distinct category of MEK inhibitors that stabilize RAF-MEK complexes and functionally suppress RAF. Although structural studies have captured these glues bound to both active and inactive RAF conformations, we show that their inhibitory activity stems from a spatial-trapping mechanism: we found that MEK is constitutively cytosolic, RAF/MEK glues sequester RAF in the cytosol, blocking its membrane recruitment and dimerization, steps essential for activation. In line with this mechanism, the RAF/MEK glue avutometinib, when combined with a pan-RAFi, was well tolerated at full dose and, critically, drove tumor regressions across multiple RAS-MUT models, achieving a 90% ORR compared with 0% using a conventional pan-RAFi + MEKi regimen in an insensitive RAS-MUT model. Tumor regressions corresponded with deeper MAPK pathway suppression by both pharmacodynamic and transcriptional metrics, without increased toxicity. Together, these findings reveal an unrecognized mechanism of RAF inactivation by RAF/MEK glues and show that substituting the MEKi with a RAF/MEK glue can overcome the therapeutic ceiling of current MAPK-targeting regimens, shifting outcomes from mostly stable disease to frequent tumor regressions. More broadly, this work establishes drug-induced proximity as a means to increase tumor selectivity by reprogramming the spatial and biochemical state of wild-type signaling effectors, thereby widening the therapeutic window for oncogenic pathway inhibition and providing a new paradigm for precision oncology.", "source_company": "The Tisch Cancer Institute, Icahn School of Medicine at Mount Sinai", "source_org_type": "研究机构", "row_number": 33, "target_meta": "Raf kinase", "MOA_meta": "抑制剂"}, {"drug_name": "PMG-A9", "company": "Promedigen", "org_type": "公司", "target": "未披露", "modality": "inhibitor", "importance_level": "中", "total_score": 59.5, "institution_score": 45, "track_score": 75, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 4, "brief_reason": "PMG-A9为口服小分子，通过恢复关键肿瘤抑制因子活性并抑制FoxM1转录因子，针对广泛癌种尤其是CRC的耐药问题。公司为韩国新兴biotech，preclinical阶段显示单药疗效及与化疗协同，机制新颖但靶点未明确披露。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8893", "id": "fVXM_5wBX1NQZOEH-LG5", "source_drug_name": "PMG-A9", "title": "A first-in-class orally bioavailable small molecule tumor suppressor activator for the treatment of a wide range of cancers", "abstract_text": "Novel therapeutic agents capable of restoring the function of key tumor suppressors, frequently inactivated across a wide spectrum of cancers, represent a powerful strategy to address the limitations of current treatments and mitigate resistance to existing therapies. Using colorectal cancer (CRC) as a primary indication, we developed an orally bioavailable small-molecule agent, PMG-A9, that restores the activity of a key tumor suppressor and suppresses the oncogenic transcription factor FoxM1, a major driver of therapeutic resistance. Notably, 5-fluorouracil (5-FU), a widely used first-line CRC therapy, is known to induce substantial upregulation of FoxM1. In this study, we demonstrate that PMG-A9 induces a robust, dose-dependent reduction of 5-FU-driven FoxM1 expression in colorectal cancer cells. Exposure of 5-FU-treated cells to PMG-A9 promotes apoptosis through pro-apoptotic mediators, including PUMA. In preclinical CRC xenograft models, PMG-A9 exhibits robust single-agent antitumor efficacy and shows pronounced synergy when combined with multiple chemotherapeutic agents, including 5-FU, while effectively downregulating FoxM1 in vivo. These findings highlight tumor-suppressor reactivation as a promising, broadly applicable therapeutic strategy to improve treatment outcomes for CRC and, potentially, overcome drug resistance across diverse tumor types.\n*Corresponding authors: Hee-Sung Park; hee-sung.park@promedigen.com, Chakrapani Subramanyam; subramanyam@promedigen.com", "source_company": "Promedigen", "source_org_type": "公司", "row_number": 183, "target_meta": "not available", "MOA_meta": "抑制剂"}, {"drug_name": "FID-031", "company": "Fulgent Pharma", "org_type": "公司", "target": "HER2", "modality": "ADC", "importance_level": "中", "total_score": 59.5, "institution_score": 55, "track_score": 90, "milestone_score": 40, "field_heat_score": 75, "bonus_score": 3, "brief_reason": "FID-031为新型HER2靶向ADC，采用专有亲水性稳定连接子及拓扑异构酶I抑制剂有效载荷，在动物模型中显示优于T-DXd的PK、肿瘤分布、渗透及持续疗效。Fulgent Pharma为Fulgent Genetics子公司临床阶段小型biotech公司，非头部MNC，赛道热门但仅preclinical阶段导致总分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4313", "id": "ZlXM_5wBX1NQZOEH-LS6", "source_drug_name": "FID-031", "title": "Novel HER2 antibody drug conjugates with stable hydrophilic linkers", "abstract_text": "Background: The success of Trastuzumab deruxtecan (T-DXd) was previously attributed to its unique cleavable linker and membrane permeable payload. However, the robust efficacy in cancers with ultralow HER2 expression demands further understanding of its anti-tumor mechanisms. In addition, the occurrence of severe adverse events and the development of drug resistance in clinical settings highlights the importance of designing new ADCs with improved pharmacokinetics (PK) and alternative payloads. Here we present the mechanistic study of a novel HER2-directed ADC with an attempt to improve drug biodistribution, therapeutic window, and sustained efficacy.\nMethods: HER2-targeting ADC (FID-031) with a proprietary linker and a topoisomerase I inhibitor payload has been developed with an estimated drug to antibody ratio of 7 and evaluated by HPLC, SEC, HIC, ELISA, flow cytometry and cell viability assays in vitro. PK and tissue distribution of the ADC were evaluated in CD-1 mice and tumor bearing SCID mice. In vivo efficacy and anti-tumor mechanism were explored in CDX mouse models.\nResults: FID-031 showed both HER2-dependent cytotoxicity and a bystander killing effect comparable to the control ADC (T-DXd). In various CDX models, FID-031 demonstrated significantly improved and more sustained tumor growth inhibition than T-DXd at 1-3 mg/kg dose levels. In CD-1 mice, the levels of FID-031 and total antibody exhibited a prolonged half-life in circulation. In HER2-positive tumor-bearing mice, the free payload level from FID-031 was relatively low in plasma but significantly higher in tumor tissue compared to T-DXd, correlating with its superior efficacy in animal models. Immunohistochemistry of FID-031 revealed higher antibody distribution in the tumor microenvironment and deeper penetration in tumor parenchyma compared to T-DXd control. In both HER2 high- and low-expression CDX models, cancer-associated fibroblast and tumor-associated macrophage colocalized with ADC in the tumor microenvironment, suggesting critical roles of these cells in the ADC biological metabolism. Comparable levels of free payload accumulation were observed in normal tissues (i.e., lung, liver, kidney and spleen) for both FID-031 and T-DXd. Significantly lower level of free payload was observed in intestine tissue within the FID-031 treatment group compared to the T-DXd control group. In vivo toxicology studies in NHP are in progress.\nConclusions: FID-031 is a novel HER2-targeting ADC with improved PK profile, tissue distribution, and efficacy. This study provides fresh insights on the design considerations for ADC development aimed towards improving safety and overcoming drug resistance.", "source_company": "Fulgent Pharma", "source_org_type": "公司", "row_number": 284, "target_meta": "HER2", "MOA_meta": "抗体偶联药物"}, {"drug_name": "EPIC", "company": "Sungkyunkwan University", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "中", "total_score": 59.5, "institution_score": 35, "track_score": 85, "milestone_score": 65, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "EPIC为酶控开关聚合物缀合物，通过cathepsin B激活在溶酶体中产生ROS诱导gasdermin-D介导的pyroptosis，促进免疫原性细胞死亡并协同抗PD-1实现肿瘤消退。大学机构分数较低，但pyroptosis诱导+纳米治疗+免疫协调机制新颖且在热门免疫治疗领域具潜力，动物模型显示显著疗效加分。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5580", "id": "mFXM_5wBX1NQZOEH-LG6", "source_drug_name": "EPIC", "title": "Light-free photochemical internalization-inducing polymer conjugate elicits cancer pyroptosis to coordinate host immune responses", "abstract_text": "Gasdermin-D-mediated pyroptosis, an immunogenic cell death primarily occurring in antigen-presenting cells, plays a pivotal role in coordinating both innate and adaptive immune responses. Therefore, it holds immense potential for cancer immunotherapy. However, its spatiotemporal control within the tumor microenvironment remains challenging. We developed EPIC (Enzymatically switchable Pyroptosis-Inducing polymer Conjugate) within lysosomes upon exposure to cathepsin B, an enzyme overexpressed in many cancers. Upon in vitro exposure to cancer cells, EPIC generates reactive oxygen species via self-immolation-mediated CRET. The resulting oxidative stress induces lysosomal membrane destabilization, which initiate a downstream signaling cascade leading to proteolytic cleavage of gasdermin-D. The cleaved gasdermin-D assembles into pyroptotic pores in the cell membrane, enabling the efflux of damage-associated molecular patterns and pro-inflammatory cytokines. Systemic administration of EPIC in tumor-bearing mice invokes a potent immune response by dendritic cell maturation and reinvigoration of cytotoxic NK cells. Notably, combining EPIC with anti-PD-1 checkpoint blockade enhances the infiltration of tumor-specific cytotoxic T lymphocytes, resulting in sustained tumor regression and complete remission in over 50% of treated mice. These findings underscore the potential of EPIC as a multifunctional, precisely activatable nanotherapeutic for effective cancer immunotherapy.", "source_company": "Sungkyunkwan University", "source_org_type": "大学", "row_number": 413, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "LSD1 allosteric inhibitor", "company": "Kyoto University", "org_type": "大学", "target": "LSD1 (non-catalytic, allosteric site)", "modality": "inhibitor", "importance_level": "中", "total_score": 59.5, "institution_score": 35, "track_score": 75, "milestone_score": 80, "field_heat_score": 85, "bonus_score": 4, "brief_reason": "药物为靶向LSD1非催化支架功能的变构抑制剂，可选择性抑制MITF-low耐药黑色素瘤并延缓BRAF抑制剂及抗PD-1耐药发生，具有新机制亮点。机构为大学得分较低，但赛道新颖性强、前临床数据扎实且跨癌种潜力带来较高综合热度。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/2106", "id": "zVXM_5wBX1NQZOEH-LG6", "source_drug_name": "LSD1 allosteric inhibitor", "title": "Druggable dependency on histone demethylase LSD1 in MITF-low therapy resistant melanoma", "abstract_text": "Acquired and intrinsic resistance to targeted and immune therapies in melanoma is associated with an undifferentiated, mesenchymal-like tumor cell state characterized by low expression of the melanocytic lineage regulator MITF and high expression of the receptor tyrosine kinase AXL. Because MITF governs lineage-specific survival and differentiation programs, therapy-resistant MITF-low/AXL-high melanomas appear to evade these programs and instead depend on alternative survival mechanisms. To uncover such dependencies, we systematically interrogated genome-scale CRISPR-Cas9 knockout screens from the Cancer Dependency Map and identified a selective vulnerability to the epigenetic regulator lysine-specific demethylase 1 (LSD1/KDM1A). Intriguingly, domain-focused CRISPR screening spanning whole LSD1 coding locus further revealed that this dependency is mediated through non-catalytic, scaffold-like functions of LSD1 rather than its demethylase activity. Mechanistically, integrated LSD1 ChIP-seq, histone ChIP-seq (H3K4me1/2/3 and H3K27ac) and RNA-seq analyses demonstrated that LSD1 sustains a survival program characterized by chromosome segregation and neuronal dedifferentiation in MITF-low melanoma, orchestrated through distinct super-enhancer activation at key regulators, such as CDC6, related to these pathways. Disruption of LSD1’s non-catalytic activity by a LSD1 allosteric inhibitor induced G2/M arrest, transcriptional reprogramming, and growth inhibition selectively in MITF-low melanomas via downregulation of CDC6. Strikingly, genetic and pharmacological ablation of LSD1’s non catalytic function significantly prevented or delayed the emergence of resistance to BRAF inhibition and anti-PD-1 therapy in vitro, in vivo, and in patient-derived melanoma organoids. Furthermore, pan-cancer analyses revealed a similar LSD1 dependency in other poorly differentiated malignancies, including pancreatic cancer, that share an undifferentiated transcriptional state. Collectively, these findings define an epigenetically determined, therapeutically targetable state that underlies treatment resistance across multiple cancer types. By targeting the non-catalytic scaffolding function of LSD1, either alone or in combination with targeted and immune therapies, it may be possible to eradicate undifferentiated, drug-tolerant tumor cell populations and overcome therapeutic resistance in melanoma and other aggressive cancers.", "source_company": "Kyoto University", "source_org_type": "大学", "row_number": 457, "target_meta": "LSD1", "MOA_meta": "抑制剂"}, {"drug_name": "Ad-BiME", "company": "University of Oxford", "org_type": "大学", "target": "未披露", "modality": "oncolytic virus", "importance_level": "中", "total_score": 59.5, "institution_score": 45, "track_score": 75, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "Ad-BiME为溶瘤腺病毒表达的bispecific macrophage engager（BiME），通过促进肿瘤抗原的非特异性交叉呈递增强适应性免疫，但靶点未明确披露。大学机构分数中等，溶瘤病毒+双特异性免疫衔接器赛道较热，体外和ex vivo实验显示优于anti-CD47的吞噬和激活效果及肿瘤特异性，具有一定preclinical潜力。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9701", "id": "KFXM_5wBX1NQZOEH-LK6", "source_drug_name": "Ad-BiME", "title": "Promoting improved agnostic cross presentation of tumor antigens with an oncolytic adenovirus expressing bispecific macrophage engagers", "abstract_text": "Background: Non-specific (‘agnostic’) cross-presentation of tumor antigens (TAA) is essential for generating adaptive immune responses against cancer. APCs uptake TAA by phagocytozing proteins from cancer cells and present them on HLA molecules to activate T cells.To induce cancer cell uptake by the APCs, we aimed develop a bispecific macrophage engager (BiME) that can bring cancer cells and APCs into close proximity, and we hypothesized that oncolytic viruses could be used to express BiMEs in the tumor microenvironment.\nMethods: We generated an oncolytic adenovirus expressing a BiME (Ad-BiME) designed to bind a tumor-associated antigen on cancer cells and an activating receptor on APCs, thereby promoting interaction and triggering APC activation. The expressed bispecific protein efficiently bound ligands on both APCs and cancer cells. Co-culture assays evaluated phagocytosis, macrophage activation, and antigen cross-presentation. To analyse cross-presentation, we engineered NY-ESO-1-expressing HLA-A2-negative cancer cells and co-cultured them with HLA-mismatched HLA-A2-positive APCs. NY-ESO-1(157-165) peptide-loaded HLA-A2-specific 1G4 TCR primary T cells detected cross-presentation. Finally, freshly dissected colorectal tumor and normal colon biopsies were used to assess cancer-specific virus replication, BiME generation, and macrophage activation.\nResults: The BiME significantly enhanced phagocytosis of cancer cells by macrophages, surpassing the clinically tested anti-CD47 antibody. It further activated macrophages, upregulating CD86 and CD80 expression. Notably, Ad-BiME induced the strongest macrophage activation. Tumor antigen cross-presentation by macrophages was markedly increased following BiME treatment. Ex vivo experiments showed that oncolytic viruses replicated and produced BiME exclusively in colorectal tumor biopsies, where they induced endogenous macrophage activation, unlike in normal tissues. Elevated IL-1β, TNF, IL-6, CXCL10, and IFN-γ were detected only in tumor samples, indicating targeted BiME expression. Interestingly, free BiME treatment markedly increased CCL17, a chemokine attracting regulatory T cells (Tregs). In contrast, Ad-BiME did not elevate CCL17, likely due to gradual in situ BiME generation. Bulk RNA analysis further revealed that Ad-BiME uniquely upregulated macrophage pathways linked to antigen cross-presentation and T-cell chemotaxis.\nConclusion: We generated the first oncolytic virus expressing a BiME and demonstrated its potential as a promising mechanism for antigen-agnostic cross-presentation in developing cancer vaccines for solid tumors.", "source_company": "University of Oxford", "source_org_type": "大学", "row_number": 514, "target_meta": "not available", "MOA_meta": "溶瘤病毒"}, {"drug_name": "PanTarg ADC", "company": "PanTarg ApS", "org_type": "公司", "target": "uPAR", "modality": "ADC", "importance_level": "中", "total_score": 59.5, "institution_score": 45, "track_score": 80, "milestone_score": 50, "field_heat_score": 75, "bonus_score": 5, "brief_reason": "靶向uPAR的双靶向（肿瘤+基质）ADC，机制新颖可克服PDAC等致密基质肿瘤障碍，preclinical显示强效抗瘤、Bystander杀伤及免疫调控。机构为2024年成立丹麦初创公司非头部，赛道ADC+新兴uPAR靶点热度较高但开发早期。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5458", "id": "XlXM_5wBX1NQZOEH-LK6", "source_drug_name": "PanTarg ADC", "title": "Unveiling the PanCancer potential of dual-targeting uPAR-directed ADCs across cancers", "abstract_text": "Antibody-drug conjugates (ADCs) are revolutionizing cancer therapy; yet, their impact in solid tumors remains limited, partly because most approved ADCs primarily target tumor-associated antigens on malignant cells. This tumor-centric approach is often insufficient in highly desmoplastic cancers such as pancreatic ductal adenocarcinoma (PDAC), where the dense, immunosuppressive stroma promotes tumor progression, restricts drug penetration, and contributes to therapeutic resistance. Targeting both malignant and stromal compartments is therefore a critical unmet need to enhance ADCs' efficacy in these refractory tumors. To address this gap, PanTarg is advancing a novel ADC that targets both the cancer and the surrounding stromal compartment. The ADC specifically targets the urokinase plasminogen activator receptor (uPAR), which is broadly overexpressed across tumor and stromal populations in aggressive cancers, particularly PDAC, while minimally expressed in normal tissues. This dual-targeting strategy aims to overcome stromal barriers and support a broader, potentially Pan-Cancer therapeutic approach. PanTarg’s ADC leverages a proprietary uPAR antibody with optimal biophysical and ADC properties. In preclinical models of PDAC and other uPAR-positive tumors, PanTarg ADCs demonstrated potent anti-tumor activity across multiple payload classes. Mechanistic studies revealed stromal targeting, bystander killing of uPAR-negative cancer cells, and immune-modulatory effects promoting a more permissive tumor microenvironment. Moreover, the ADCs showed favorable tolerability consistent with uPAR’s restricted expression profile. Overall, these findings validate uPAR as a clinically relevant dual-compartment ADC target and position PanTarg as a promising next-generation therapeutic candidate for PDAC and, more broadly, aggressive uPAR-positive cancers.", "source_company": "PanTarg ApS", "source_org_type": "公司", "row_number": 545, "target_meta": "PLAUR", "MOA_meta": "抗体偶联药物"}, {"drug_name": "RAS-AUTOTAC", "company": "Seoul National University", "org_type": "大学", "target": "RAS (KRAS variants)", "modality": "other", "importance_level": "中", "total_score": 59.5, "institution_score": 35, "track_score": 90, "milestone_score": 55, "field_heat_score": 85, "bonus_score": 5, "brief_reason": "RAS-AUTOTAC利用AUTOTAC平台通过自噬途径靶向降解活性GTP-bound RAS形式，实现广谱KRAS变异体信号抑制，针对‘不可成药’靶点提供新机制。机构为大学非商业化主体得分较低，但KRAS热门+新型自噬TPD赛道热度高，动物模型显示肿瘤抑制具概念验证价值。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6443", "id": "2lXM_5wBX1NQZOEH-LK6", "source_drug_name": "RAS-AUTOTAC", "title": "Targeted degradation of KRAS using the AUTOTAC platform", "abstract_text": "RAS is one of the most frequently mutated oncogenes in human cancers, with KRAS mutations being particularly prevalent: accounting for approximately 95% of pancreatic cancers, 45% of colorectal cancers, and 20% of lung cancers. Due to its lack of deep pockets for ligand binding, RAS has long been considered an “undruggable target,” despite more than three decades of intensive drug discovery efforts. Although small-molecule inhibitors targeting KRAS G12C have recently been developed, their therapeutic effect is limited to this specific mutation, underscoring the need for strategies capable of targeting a broader range of KRAS variants.AUTOphagy TArgeting Chimera (AUTOTAC) is a recently developed targeted protein degradation platform that harnesses the autophagy pathway to eliminate pathological proteins. In this study, we applied AUTOTAC technology to RAS, generating RAS-AUTOTAC, a bifunctional small molecule composed of a Target-Binding Ligand (TBL) linked to an Autophagy-Targeting Ligand (ATL). Upon binding to RAS via the TBL, the ATL component recruits the ZZ domain of p62, inducing p62 oligomerization and initiating autophagic degradation. During this process, RAS becomes biologically inactivated and sequestered into autophagosomes. RAS-AUTOTAC suppresses downstream oncogenic signaling through p62 oligomerization and subsequent autophagic degradation. Importantly, RAS-AUTOTAC selectively recognizes the GTP-bound active form of RAS and effectively suppresses RAS signaling across multiple KRAS variants. Moreover, RAS-AUTOTAC demonstrated tumor growth inhibition in animal models, supporting its functional activity in vivo.Collectively, our results provide a mechanistic basis for applying AUTOTAC to RAS-driven cancers.", "source_company": "Seoul National University", "source_org_type": "大学", "row_number": 630, "target_meta": "KRAS", "MOA_meta": "其他"}, {"drug_name": "SMG1 inhibitor", "company": "University College London Cancer Institute", "org_type": "研究机构", "target": "SMG1", "modality": "inhibitor", "importance_level": "中", "total_score": 59.5, "institution_score": 35, "track_score": 85, "milestone_score": 70, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "靶向SMG1抑制NMD通路以稳定frameshift转录本、提升免疫原性neoantigen呈现，机制新颖且可增强ICB疗效。机构为大学研究机构得分较低，但NMD抑制作为免疫治疗新策略赛道热度高，前临床多模型验证强度较好。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10447", "id": "KVXM_5wBX1NQZOEH-LO6", "source_drug_name": "SMG1 inhibitor", "title": "Nonsense-mediated mRNA decay inhibition augments in vitro, in vivo, and ex vivo anti-tumor immunity", "abstract_text": "Introduction: Neoantigens from somatic tumor mutations are essential for effective anti-tumor immune responses. Frameshift insertions and deletions (fs-indels) represent a rare but highly immunogenic mutation subtype, as they create novel open reading frames (neoORFs) that generate peptides that are significantly distinct from self-antigens. Nevertheless, fs-indels often introduce premature termination codons, leading to transcript degradation via the nonsense-mediated mRNA decay (NMD) pathway, leading to loss of immunogenic neoantigen.\nApproach: For the first time, we pharmacologically inhibited SMG1, a core component of the NMD pathway, across a range of preclinical models, including human and mouse cancer cell lines, patient-derived tumor organoids (PDTOs), patient-derived tumor fragments (PDTFs), and syngeneic mouse xenografts. We analyzed the changes in transcriptome, proteome, and immunopeptidome following SMG1 inhibition (SMG1i) and peptide reactivity in in vitro priming experiments. We then combined tumor-T cell co-cultures and PDTFs to assess the anti-tumor immunogenicity induced by SMG1i. Ex vivo and in vivo immunological responses were assessed by high-dimensional flow cytometry, cytometric bead array, and single-cell RNA- and TCR-sequencing.\nResults: Using multi-omic and checkpoint inhibitor (CPI) response data from over 1,000 patients, we show that decreased expression of the key NMD mediator, SMG1, correlates with improved CPI response. Inhibiting SMG1 ex vivo and in vivo activates and expands tumor-reactive T cells and sensitizes CPI efficacy. Mechanistically, SMG1 inhibition stabilizes frameshift-derived transcripts, increasing the abundance and surface presentation of immunogenic neoantigens. This results in an increase in neoepitope burden in tumors, similar to that seen in tumors with high tumor mutational burden (TMB), without inducing DNA damage. Co-culturing tumor cells and PDTOs with CD8+ T cells after SMG1i results in strong MHC class I antigen-dependent T cell activation and tumor cell killing.\nConclusion: Our findings highlight SMG1 inhibition as a promising strategy to exploit an untapped source of highly immunogenic peptides. It enhances anti-tumor immunogenicity without introducing DNA mutations, regardless of tumor type or TMB status, providing translational evidence for sensitizing ICB responses.", "source_company": "University College London Cancer Institute", "source_org_type": "研究机构\n大学", "row_number": 679, "target_meta": "SMG1", "MOA_meta": "抑制剂"}, {"drug_name": "HIP B7H3 CAR-T cells", "company": "Cedars Sinai Medical Center", "org_type": "医院", "target": "B7-H3", "modality": "CAR", "importance_level": "中", "total_score": 59.5, "institution_score": 35, "track_score": 85, "milestone_score": 65, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "靶向B7-H3的同种异体低免疫原性（HIP）CAR-T细胞，通过敲除B2M/CIITA/TRAC并过表达CD47实现免疫逃逸，在体外和体内模型中对胆管癌保持完整抗肿瘤活性。机构为医院/学术中心而非头部药企得分较低，但CAR-T结合HIP平台针对实体瘤热门靶点B7-H3且preclinical数据扎实，整体潜力中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5255", "id": "X57ECZ0BZznHJdntvNYd", "source_drug_name": "HIP B7H3 CAR-T cells", "title": "B7-H3 hypoimmune chimeric antigen receptor T cells overcome immune rejection and retain antitumor activity against cholangiocarcinoma", "abstract_text": "Background. Intrahepatic cholangiocarcinoma (ICC) is a rare, aggressive liver cancer, with limited treatment options and poor survival. Because surgery is the only curative option, but most patients present with advanced disease, novel therapies are urgently needed. CAR-T cell therapy has revolutionized hematologic cancer treatment, but its application in solid tumors is limited.We investigated an allogeneic “off-the-shelf” hypoimmune (HIP) CAR-T platform designed to overcome barriers that hinder CAR-T efficacy in solid tumors. Targeting B7-H3, aberrantly expressed in ICC, the HIP CAR T cells demonstrated promising activity in vitro and in vivo studies. These findings support the potential of allogeneic HIP B7H3 CAR-T cells to improve antitumor responses in advanced ICC.\nMethods: Immunohistochemical staining of an ICC tumor vs normal tissue. Generation of HIP T cells with disrupted B2M, CIITA, and TRAC genes using CRISPR-Cas9 editing. In addition, CD47 and anti-B7H3 CAR were expressed using lentiviral transduction. These allogeneic HIP B7H3 CAR T cells were compared to allogeneic WT B7H3 CAR T cells (TCR-/-) that only expressed the anti-B7H3 CAR. HIP phenotype characterization was analyzed by flow cytometry. Killing assay performed with xCELLicence real-time system. BLI for tumor growth.\nResults: Immunohistochemistry of human ICC tumors showed strong membrane and cytoplasmic B7-H3 expression compared to normal liver tissue. The B7-H3 epitope recognized by mAb 376.96 was highly expressed in ICC2, ICC3 and hCAF cell lines. B7-H3 CAR T specifically recognized and eliminated ICC targets in vitro. Lentiviral constructs engineering produced both WT and HIP allogeneic CAR T cells with high editing efficiency: TCR knockout in 91% (WT) and 89.8% (HIP) and HLA-I and HLA-II knocked out in 93.3% and 98.7% of HIP B7-H3 cells. CD47 overexpression was restricted to the HIP B7-H3 cells (47.3%). In co-culture assay T cells, NK cells, and macrophages, HIP cells showed protection from adaptive and innate immune clearance. Impedance cytotoxicity assays confirmed that HIP B7-H3 CAR T cells maintained full antitumor activity, matching WT B7-H3 CAR T cell killing rate. HIP CAR-T cells are now validated in in vivo ICC model.\nConclusion: Our findings showed that allogeneic HIP B7-H3 CAR T cells can be efficiently engineered, maintain protection from adaptive and innate immune rejection, and retain full cytotoxic activity against ICC tumors. By combining the tumor-specific activity of B7-H3 CAR-T cells with the immune-evasive properties of HIP cells, this approach offers a promising and widely applicable allogeneic “off-the shelf” therapy for ICC, providing a strong rationale for further preclinical translational studies.", "source_company": "Cedars Sinai Medical Center", "source_org_type": "医院", "row_number": 724, "target_meta": "CD276", "MOA_meta": "其他"}, {"drug_name": "TNF-alpha armed TCR-T cells", "company": "University of California, Los Angeles", "org_type": "大学", "target": "未披露", "modality": "CAR", "importance_level": "中", "total_score": 59.5, "institution_score": 35, "track_score": 85, "milestone_score": 65, "field_heat_score": 75, "bonus_score": 4, "brief_reason": "TNF-α武装的TCR-T/CAR-T细胞针对实体瘤，通过抗原依赖性局部释放TNF-α显著提升杀伤效能并改善肿瘤微环境，无系统毒性；大学机构得分较低，但CAR-T改造+实体瘤突破赛道热度高，前临床数据较强且具新机制亮点。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5213", "id": "b57ECZ0BZznHJdntvNYd", "source_drug_name": "TNF-alpha armed TCR-T cells", "title": "Tumor necrosis factor-alpha armed TCR-T and CAR-T cells for solid tumors provide superior anticancer activity in the absence of toxicity", "abstract_text": "Background: TCR-T and CAR-T cells directed against tumor-specific antigens are associated with robust initial clinical responses which are often not durable against solid tumors, demonstrating an urgent need for more potent cell therapy products. We created TNF-alpha (TNF-a) armed variants of TCR-T and CAR-T cells to test their effectiveness and toxicity against a variety of solid tumors.\nMethods: Lentiviral vectors encoding the TCR/CAR of interest with or without a supplemental copy of TNF-a were generated for NY-ESO-1 TCR, HPV-16 E7 TCR, and GD2 CAR. Mock, conventional TCR/CAR, and TNF-a armed TCR/CAR T-cells were co-cultured with nRFP-transduced tumor cells expressing the corresponding tumor antigen and appropriate HLA-A haplotype for the TCR-T cells (A375/M257-A2 melanoma cells for NY-ESO-1, 4050/CaSki cervical carcinoma cells for HPV-16 E7, and 143B/G292 osteosarcoma cells for GD2). Cells were subjected to repetitive stimulation assays to assess tumor killing efficiency in the setting of chronic antigen exposure. In parallel, in vivo tumor challenges were performed using humanized NSG mouse xenografts treated with mock, conventional TCR/CAR, or TNF-a-armed TCR/CAR T-cells. Mice were subjected to end of study necropsies to assess end-organ toxicity. T-cell phenotypes in circulation and intratumorally were assessed via flow cytometry, while serum cytokines were assessed weekly via multiplex sandwich ELISA. Tumors were also subjected to spatial transcriptomic analysis via CosMx.\nResults: In vitro, TNF-a-armed TCR/CAR T-cells displayed significantly increased tumor cell killing and significantly increased secretion of TNF-alpha both initially and over time, exclusively in a tumor antigen-dependent manner. In vivo, TNF-a-armed TCR/CAR T-cells displayed superior tumor control and mouse survival compared to the corresponding conventional TCR/CAR. Importantly, this superior tumor control occurred in the absence of any systemic increases in TNF-a or IL-6, systemic toxicity (temperature, weight, body condition score), as well as without any differences in end-organ inflammatory damage/lymphocytic infiltration. Tumors treated with TNF-a-armed TCR/CAR T-cells displayed significantly increased T-cell infiltration, as well as significant reductions in intratumoral MDSCs, CD4 Tregs and Th2 cells and associated cytokines, while tumor cells displayed significant increases in TNF-a signaling, and significant decreases in IL-10 immunosuppressive pathways arising from the Tregs.\nConclusions: TNF-a-armed TCR/CAR-T cells possess superior antitumor efficacy against a wide variety of solid tumors, in the absence of any systemic toxicity, due to the antigen-dependent nature of the increased TNF secretion. This is due to both increased local TNF-a secretion and antitumor effector activity, as well as decreased Treg activity within the tumor.", "source_company": "University of California, Los Angeles\nUniversity of California Los Angeles", "source_org_type": "大学", "row_number": 879, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "neutralizing antibody against GDF-15", "company": "Johns Hopkins University", "org_type": "大学", "target": "GDF-15", "modality": "neutralizing antibody", "importance_level": "中", "total_score": 59.5, "institution_score": 40, "track_score": 75, "milestone_score": 70, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "药物为针对GDF-15的中和抗体，机制通过阻断GDF-15改善PDAC老年模型的免疫抑制微环境并增强免疫治疗效果。机构为大学非商业研发导致institution_score较低，但靶点在免疫抑制与肿瘤微环境领域热度高、preclinical组合治疗显示协同潜力，故总体为中重要性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/2045", "id": "oJ7M_5wBZznHJdnt_W3O", "source_drug_name": "neutralizing antibody against GDF-15", "title": "Overcoming aging-driven barriers to effective immunotherapy in pancreatic cancer", "abstract_text": "Background: Immunotherapies such as immune checkpoint inhibitors (ICIs) and cancer vaccines have transformed the treatment of several cancers, yet pancreatic ductal adenocarcinoma (PDAC) remains largely refractory. PDAC has a dismal 5-year survival rate of ~13%, and therapeutic resistance has been attributed to the profoundly immunosuppressive tumor microenvironment (TME). Multiple preclinical strategies have been proposed to overcome stromal and immune barriers in PDAC, but translation to patients has not yet successfully sensitized PDAC to immunotherapy, underscoring the need for new approaches.PDAC is a disease of aging, with a median age at diagnosis of 71 and >90% of cases diagnosed after age 55. Normal biological aging alters both stromal and immune compartments: immunosenescence reduces the pool of naïve T cells and diminishes antigen-presenting cell (APC) function, while fibroblast remodeling alters paracrine signaling and stromal interactions in normal tissues. Our prior work established that aging also alters the PDAC tumor microenvironment. We found that as pancreatic fibroblasts age, they secrete ligands that directly enhance PDAC cell growth and invasion, leading to faster tumor growth and increased metastatic spread. This matches with clinical data showing that older patients with PDAC have more aggressive disease at diagnosis and inferior outcomes compared to younger patients even when controlling for all other relevant clinical factors.\nOur group has also recently defined age-associated differences in the circulating and tumor-infiltrating T-cell pool across patients with cancer. Older individuals harbor fewer naïve T cells that have higher baseline expression of immune checkpoints, suggesting that these aged T cells appear less capable of mounting new antigen-specific responses. We therefore hypothesize that immune aging directly limits the efficacy of cancer vaccines in older patients and that interventions restoring antigen presentation and T-cell priming may be required in patients with PDAC. Despite these observations, most preclinical PDAC models fail to incorporate the biological effects of aging, limiting translational relevance.\nTo model this biology directly, we developed aged-host PDAC systems and observed that aging drives expression of multiple immunosuppressive cytokines in the TME. Among these, growth differentiation factor-15 (GDF-15), a stress- and aging-induced member of the TGF-β superfamily, has emerged as a candidate mediator of age-associated immune dysfunction, which may limit the efficacy of cancer vaccine therapies. Our work has established that aged pancreatic fibroblasts express high levels of GDF-15, which promotes progression of PDAC tumors. GDF-15 is known to suppress dendritic cell maturation, limit antigen presentation, and restrict CD8⁺ T-cell infiltration in other contexts. These observations raise the possibility that GDF-15 contributes to T-cell exclusion and diminished vaccine responsiveness in older hosts, which represents the overwhelming majority of patients with PDAC.\nMethods and Results: To interrogate how aging shapes the PDAC tumor immune microenvironment, we implanted orthotopic KPC and KPCY tumors into young (8-12 weeks) and aged (>12 months) C57BL/6 mice, including cohorts with systemic knockout of GDF-15. Tumors were profiled by flow cytometry, immunohistochemistry, and imaging mass cytometry to quantify immune compartments. Across multiple PDAC models in aged hosts, tumors contained significantly fewer dendritic cells (DCs) than those in young mice, suggesting reduced antigen-presenting capacity. We also identified a significant decrease in both CD4+ and CD8+ T cell infiltration in tumors from aged compared to young mice. These deficiencies were associated with impaired vaccine immunogenicity: aged mice given a pooled mutant KRAS (mKRAS) vaccine, incorporating peptides from the six most common alleles, which are present in ~90% of PDAC patients, mounted much weaker interferon-γ responses on ELISpot than young controls, consistent with impaired generation of new antigen-specific immunity during aging.Cytokine profiling revealed that aged PDAC tumors expressed higher levels of multiple immunosuppressive mediators, with growth differentiation factor-15 (GDF-15) emerging as a dominant stromal signal. Aged pancreatic fibroblasts expressed abundant GDF-15, and circulating GDF-15 was elevated in aged PDAC-bearing mice compared to young. Importantly, analysis of the Human Protein Atlas demonstrated that serum GDF-15 is highly elevated in patients with PDAC compared to both healthy volunteers and patients with other types of cancer, underscoring its disease relevance and the importance of age-informed PDAC models.\nTo test GDF-15’s functional impact on the tumor immune microenvironment, we administered recombinant GDF-15 to young mice bearing PDAC tumors, which resulted in accelerated tumor growth and reduced intratumoral CD8⁺ T-cell infiltration. Conversely, GDF-15 knockout in aged mice reduced tumor growth and significantly increased CD8⁺ infiltration, providing evidence that expression of GDF-15 in the microenvironment shapes the immune landscape in PDAC.\nTherapeutically, treatment with a neutralizing antibody against GDF-15, currently in clinical development, significantly reduced tumor size in aged, but not young, mice, emphasizing the age-dependence of this phenotype. However, GDF-15 blockade alone did not produce complete regressions or durable control. We therefore combined GDF-15 blockade with immune checkpoint inhibition and the mKRAS vaccine to determine if we could overcome age-induced immunosuppression and sensitize tumors to immunotherapy strategies. The combination produced significant reductions in tumor growth and was associated with marked increases in neoantigen-specific T-cell responses, as measured by ELISpot assays compared to these therapies given in isolation.\nConclusions and Impact: Our work demonstrates that aging reshapes the PDAC immune microenvironment through elevated GDF-15, promoting tumor growth and impairing vaccine-elicited T-cell responses and immunotherapy responses. Neutralization of GDF-15 significantly reduced tumor size in aged but not young models of PDAC, highlighting the age-dependence of this phenotype and the necessity of age-informed models to recapitulate human disease. While GDF-15 blockade alone did not yield durable tumor regressions, combinations with checkpoint inhibitors and mutant KRAS vaccination produced substantial tumor growth inhibition and robust neoantigen-specific T-cell responses, supporting a novel therapeutic strategy to overcome resistance.\nThis body of work establishes immune aging as a barrier to immunotherapy and identifies GDF-15 as a key mediator that links stromal remodeling to impaired antitumor immunity. The findings provide immediate translational potential. Neutralizing antibodies targeting GDF-15 are in clinical development, and our data directly support their study in PDAC, particularly in older patients who shoulder the greatest disease burden. Treating aging as a biological determinant of therapy resistance may help identify additional pathways that can be therapeutically targeted. More broadly, our work provides a framework for integrating aging biology into the design of cancer immunotherapies across solid tumors, ensuring that future interventions account for the molecular features of cancer in older patients. Ultimately, this approach lays the groundwork for age-adapted immunotherapy strategies that could extend the benefits of vaccination and checkpoint blockade to patients who currently derive diminished benefit from these transformative therapies.", "source_company": "Johns Hopkins University", "source_org_type": "大学", "row_number": 1060, "target_meta": "GDF15", "MOA_meta": "抗体"}, {"drug_name": "Multispecific T cell Engager (MTE)", "company": "Seattle Children's Research Institute", "org_type": "研究机构", "target": "CD19 AND CD33", "modality": "TCE", "importance_level": "中", "total_score": 59.5, "institution_score": 35, "track_score": 85, "milestone_score": 70, "field_heat_score": 80, "bonus_score": 6, "brief_reason": "CD19/CD33双靶点AND逻辑门控TCE，通过亲和力优化实现高选择性avidity机制，针对B-myeloid MPAL这一高危亚型。研究机构背景拉低机构分，但热门TCE赛道+新型逻辑门控机制+较强的体外/体内POC和安全性数据支撑较高赛道与里程碑分。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9665", "id": "G57M_5wBZznHJdnt_W7O", "source_drug_name": "Multispecific T cell Engager (MTE)", "title": "Novel multispecific T cell engagers exploit avidity for highly selective targeting of B-myeloid mixed-phenotype acute leukemia", "abstract_text": "Introduction. B-myeloid mixed-phenotype acute leukemia (B-MPAL) is a high-risk leukemia subtype co-expressing lymphoid and myeloid surface antigens. Cure rates remain low, especially in adults (OS 20% to 50%). Current therapies are heterogeneous, borrowing from either ALL or AML regimens. MPAL cells uniquely co-express both lymphoid markers (e.g. CD19) and myeloid markers (e.g. CD33), a dual expression profile not shared by normal hematopoietic cells. We hypothesize that a Multispecific T cell Engager (MTE) engineered to preferentially bind cells expressing CD19 AND CD33 will achieve high selectivity compared to single-antigen targeting. We thus designed MTEs that bind both CD19 and CD33 on MPAL cells and CD3 on T cells. We fine-tuned the affinity of the CD19 and CD33 binders to leverage avidity; this ensures poor binding to single-positive (SP) normal cells but high-avidity binding to double-positive (DP) leukemia cells. This strategy aims to induce deep remissions and improve safety over single-target agents like Blinatumomab.\nMethods. We successfully designed and produced 30 tri-specific CD19/CD33/CD3 MTEs, utilizing components derived from de-risked or FDA-approved therapeutics. Our MTE framework is an asymmetric \"knob into hole\" human IgG1 scaffold incorporating effector silencing mutations. In vitro assays tested binding and T cell cytotoxicity against DP, SP, or negative cell lines. Top candidates were tested in vivo using a luciferase-labeled JIH-5 xenograft (CD19+ CD33+) model in NSG-SGM3 mice. Engrafted mice received repeated weekly doses of MTEs and human T cells, with disease progression tracked via IVIS imaging.\nResults. In vitro data confirm successful dual-antigen targeting and dramatic specificity improvements using lower-affinity binders. For multiple candidates, we observed much lower cytotoxicity for SP cells, with up to a 7-log difference in IC50​ between DP and SP cells, demonstrating an AND logic-gated treatment within a single molecule. Initial preclinical in vivo data show successful control of disease progression in xenografted mice at well-tolerated doses. Crucially, we conducted safety studies in huNOG-EXL humanized mice (engrafted with CD34+ cells) to test toxicity on normal human hematopoietic cells. Dose titration confirmed the selective sparing of normal human B cells and CD33+ myeloid cells, a major advancement over single-targeting therapies.\nConclusions. By taking advantage of the unique DP features of B-MPAL cells, we developed a novel immunotherapy that offers improved half-life, potency, selectivity, and safety. This work establishes proof of concept that the combinatorial use of binders with optimized affinity generates highly specific immunotherapies with minimal normal cell cytotoxicity via an avidity-driven mechanism, paving the way for safer and more effective treatments.", "source_company": "Seattle Children's Research Institute", "source_org_type": "研究机构", "row_number": 1145, "target_meta": "CD19,CD33", "MOA_meta": "其他"}, {"drug_name": "E2-recruiting bifunctional degrader platform", "company": "University of Oxford", "org_type": "大学", "target": "未披露", "modality": "bifunctional degrader", "importance_level": "中", "total_score": 59.5, "institution_score": 35, "track_score": 85, "milestone_score": 65, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "该平台利用E2连接酶作为招募引擎开发首创双功能降解剂，可高效降解核受体（如ERα）和多种激酶，但具体靶点未固定披露。机构为大学得分较低，但TPD新机制（E2招募）+热门degrader赛道+早期细胞验证数据使其综合潜力中等偏上。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8747", "id": "Qp7M_5wBZznHJdnt_W7O", "source_drug_name": "E2-recruiting bifunctional degrader platform", "title": "Leveraging E2 ligases for induced proximity and modulation of novel cancer-relevant targets and neosubstrates", "abstract_text": "Ubiquitin-conjugating enzymes (E2s) govern ubiquitin chain topology and flux through the ubiquitin-proteasome system, thereby shaping proteostasis, DNA-damage responses, and oncogenic signaling. Although targeted protein degradation (TPD) has largely focused on E3 ligases, convergent evidence from recent chemical biology and oncology studies indicates that E2s are druggable nodes with dual therapeutic potential for reprogramming using bifunctional and molecular glue degraders. Here, we demonstrate that E2s can act as a recruitment engine for proximity-induced degradation when E3 access or cooperativity is limiting for a distinct set of targets. We introduce a first-in-class, selective, small-molecule-based bifunctional degrader platform that exploits E2 recruitment to degrade oncology-relevant targets, including nuclear receptors and kinases. In biochemical and cellular systems, the ligand engages its E2 target with high selectivity, induces proximity through ternary complex formation and degrades the protein of interest in a proteasome- and Cullen-dependent manner. We validated our approach by designing bifunctional degraders of ERα, coupling ERα and E2 ligands with short linkers, and demonstrating target degradation in MCF7, T47D, SH-SY5Y, and K562 cell lines. We demonstrate early degradation by 6 hours and maximal degradation at 24 hours with a Dmax of 85% and DC50 of 83nM. Further, by conjugating 4 kinase inhibitor scaffolds with 2-6 linker designs, we screened the proteome to cover almost 500 potential kinase targets in K562 and MCF7. We demonstrated dose-dependent degradation of dozens of kinases, including kinases of potential therapeutic interest such as SYK, FYN, and MAPK2. We observed dramatically different sensitivity to degradation across the cell lines tested, and degradation activity was more robust at the 24h timepoint compared to 5h. Collectively, these findings validate E2 ligases as functional recruiters for TPD, expanding the degrader toolbox beyond canonical E3 ligases and establishing a complementary, generalizable framework for therapeutic development.", "source_company": "University of Oxford", "source_org_type": "大学", "row_number": 1170, "target_meta": "not available", "MOA_meta": "降解剂"}, {"drug_name": "TA1", "company": "Biocytogen", "org_type": "公司", "target": "IL23R", "modality": "inhibitor", "importance_level": "中", "total_score": 59, "institution_score": 65, "track_score": 70, "milestone_score": 40, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "TA1为靶向人源IL23R的抑制剂（可能为抗体类），在Biocytogen开发的人源化小鼠模型中体外验证显著抑制IL23通路IL17A分泌，但仅限于in vitro验证，无临床或体内肿瘤疗效数据。Biocytogen作为国内头部biotech/CRO机构在抗体和模型领域有实力，IL23R在肿瘤免疫中新兴但非最热靶点，导致整体中等重要性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5332", "id": "Q57ECZ0BZznHJdntvNYd", "source_drug_name": "TA1", "title": "A novel humanized mouse model for evaluating anti-human IL23R drugs", "abstract_text": "Background:Numerous clinical studies have found increased levels of IL-23 in various autoimmune diseases, including psoriasis, inflammatory bowel disease (IBD), rheumatoid arthritis (RA), and multiple sclerosis (MS). Targeted therapy against IL-23 has made significant progress in the field of autoimmune diseases, becoming a research hotspot and a key therapeutic target. However, new research indicates that the role of IL-23 is not limited to autoimmune diseases; its potential in tumor immunotherapy is equally noteworthy. Preclinical studies have shown that IL-23 exhibits tumor-promoting properties in various cancer models and is associated with poor patient prognosis. Therefore, ablation of IL-23 or its receptors could reduce tumor burden. Most currently developed drugs targeting human IL23R do not recognize mouse IL23R, therefore mouse models cannot be used for preclinical efficacy or safety evaluations.\nMethods:To conduct preclinical evaluation of anti-human IL23R-based therapies, Biocytogen developed a novel humanized mouse model, B-hIL23R/hIL12RB1 plus/hIL12RB2 ad mice, expressing human IL23R, IL12 receptor β1, and IL12 receptor β2. The function of the humanized IL12 receptor complex was validated by stimulating isolated mouse CD4+ T cells with recombinant mouse IL12 and human IL12 and measuring mouse IFN-γ secretion. The function of the humanized IL23 receptor complex was validated by stimulating isolated mouse CD4+ T cells with recombinant mouse IL23 and human IL23 and measuring mouse IL17A secretion. The effect of the test article TA1 (provided by the client) on the humanized IL23 pathway was validated in vitro.\nResults:In vitro stimulation with mouse IL12 and human IL12 induced the secretion of mIFN-γ by CD4+ T cells of C57BL/6 mice, while human IL12 induced the secretion of mIFN-γ by CD4+ T cells of B-hIL23R/hIL12RB1 plus/hIL12RB2 ad mice, confirming the function of the humanized IL12 receptor complex. In vitro stimulation with mouse IL23 and human IL23 induced the secretion of mIL17A by CD4+ T cells of C57BL/6 mice and B-hIL23R/hIL12RB1 plus/hIL12RB2 ad mice, confirming the function of the humanized IL23 receptor complex. In vitro use of the test article TA1 (provided by the client) significantly inhibited the secretion of mouse IL17A in the humanized IL23 pathway of B-hIL23R/hIL12RB1 plus/hIL12RB2 ad mice.\nConclusionThe humanized IL12 receptor complex and humanized IL23 receptor complex in B-hIL23R/hIL12RB1 plus/hIL12RB2 ad mice are functional and provide a valuable preclinical evaluation mouse model for assessing therapies targeting human IL23 and human IL12 receptors.", "source_company": "Biocytogen", "source_org_type": "公司", "row_number": 209, "target_meta": "IL-23R", "MOA_meta": "抑制剂"}, {"drug_name": "[177Lu]Lu-atezolizumab", "company": "The University of Alabama at Birmingham", "org_type": "大学", "target": "PD-L1", "modality": "RLT", "importance_level": "中", "total_score": 59, "institution_score": 35, "track_score": 85, "milestone_score": 65, "field_heat_score": 75, "bonus_score": 3, "brief_reason": "药物为PD-L1靶向的177Lu放射性配体（RLT），在TNBC小鼠模型中显著降低肿瘤体积并延长生存，显示良好体内分布和可接受毒性。机构为大学导致institution_score较低，但RLT+PD-L1热门组合与明确preclinical疗效使整体赛道与里程碑得分较高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3914", "id": "pFXM_5wBX1NQZOEH-LG6", "source_drug_name": "[177Lu]Lu-atezolizumab", "title": "PD-L1 targeted radiotherapy can reduce tumor burden and delay tumor growth in a mouse model of triple-negative breast cancer", "abstract_text": "Introduction: Due to lack of targeted therapies, triple-negative breast cancer (TNBC) accounts for 40% of breast cancer mortalities despite only comprising 10-15% of diagnoses. Combination of PD-1/PD-L1 inhibitors with radiation therapy have been shown to have synergistic effects in TNBC. Targeted radiotherapy (TRT), in which a targeting probe is attached to a cytotoxic radioisotope, has emerged as a promising technique to deliver a therapeutic radiation payload to cells expressing the protein of interest. This is advantageous when targeting proteins such as PD-L1, which is highly expressed in TNBC and strongly upregulated after radiation-induced cytotoxicity. The purpose of this study was to assess the efficacy and safety of a novel PD-L1 targeted radiotherapy to improve immunotherapy outcomes in TNBC.\nMethods: The PD-L1-targeted antibody atezolizumab was radiolabeled with lutetium-177, a cytotoxic radioisotope, to selectively deplete PD-L1+ cells. Athymic nude mice bearing high PD-L1-expressing MDA-MB-231 tumors were treated with saline (n=6), 250µCi (n=3) or 500µCi (n=5) of [177Lu]Lu-atezolizumab. Mice were imaged with Single Photon Emission Computed Tomography (SPECT) on days 1, 3, and 7 post-treatment, informing on distribution of the tracer in the tissue. Mice were monitored for 60 days for changes in tumor volume and body weight. Upon reaching endpoints, mice were euthanized and relevant organs (tumor, spleen, liver, kidney) were collected. Clearance organs were stained with hematoxylin and eosin to assess gross pathological changes. One- and two-way ANOVAs were utilized to assess differences between tumor volumes and SPECT imaging metrics across time, and log-rank tests were used to assess differences in survival between treatment groups.\nResults: Mice treated with 500µCi or 250µCi of [177Lu]Lu-atezolizumab demonstrated a significant reduction in tumor volume compared to control by day 20 (p < 0.05) or day 24 (p < 0.05) post-treatment, respectively. Increased median survival was observed in both treated groups (35 days in control versus 52 and 60 days in 250µCi and 500µCi treated mice, respectively, p < 0.01). No weight loss was observed in any treated groups, and histology revealed minimal splenic and renal toxicity, with mild to moderate hepatotoxicity consistent with reversible changes. SPECT imaging revealed high uptake of [177Lu]Lu-atezolizumab in the tumor by day 1 post treatment and high tumor to background ratios across all three imaging timepoints.\nConclusions: Utilizing TRT to selectively deplete PD-L1+ cells resulted in decreased tumor volumes and increased survival in a mouse model of TNBC. Further, SPECT imaging validated high uptake of the PD-L1-targeted TRT within tumor tissue. These results validate [177Lu]Lu-atezolizumab as a novel PD-L1-targeted radiotherapy which has the potential to improve outcomes of immunotherapy in TNBC patients.", "source_company": "The University of Alabama at Birmingham", "source_org_type": "大学", "row_number": 425, "target_meta": "PDL1", "MOA_meta": "其他"}, {"drug_name": "COUPLrs", "company": "Massachusetts General Hospital", "org_type": "医院", "target": "未披露", "modality": "other", "importance_level": "中", "total_score": 59, "institution_score": 35, "track_score": 85, "milestone_score": 65, "field_heat_score": 75, "bonus_score": 5, "brief_reason": "COUPLrs为新型半胱氨酸反应性小分子，通过双头结构调控或破坏蛋白复合物并诱导靶蛋白降解，针对传统口袋缺失或难成药靶点具创新性。机构为医院/学术型得分较低，但赛道新颖机制+潜在靶向转录因子等难成药蛋白+POC建立使其整体重要性达中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8907", "id": "0lXM_5wBX1NQZOEH-LG6", "source_drug_name": "COUPLrs", "title": "Developing COUPLrs, dual-warhead cysteine-reactive compounds, to target oncoproteins through interaction modulation and degradation", "abstract_text": "COUPLrs (COvalent Protein Ligators) are cysteine-reactive small molecules designed to dimerize or disrupt protein complexes, thereby modulating protein function. In our previous work, we identified COUPLrs that bind to the oncogenic fusion protein EML4-ALK in non-small cell lung cancer (NSCLC) cells. These compounds engaged the EML4 rather than the ALK kinase domain targeted by clinical inhibitors. This unconventional binding disrupted ALK signaling and induced proteasome-dependent degradation of the fusion protein, establishing proof of concept that COUPLrs can engage two protein partners simultaneously, altering their interactions and stability. These findings define COUPLrs as a new mechanistic class of molecules capable of bridging or disrupting protein complexes and driving selective degradation, offering opportunities to target proteins lacking conventional binding pockets.To systematically characterize COUPLrs’ targets and interaction networks, we employed a two-pronged workflow combining Cysteine Druggability Mapping to identify reactive and accessible cysteine residues across oncogenic proteins, while SDS-PAGE and fractionation assays monitored changes in molecular weight, revealing COUPLr-involved protein complex formation. We synthesized a 32-member library of cysteine-reactive compounds with diverse scaffolds, warheads, and reactivities. Library characterization revealed proteome-wide COUPLr targets, including inter- and intramolecular protein coupling.To expand this analysis, we conducted a proteomic screen across 13 cancer cell lines representing diverse tissue origins, generating a comprehensive atlas of COUPLrs-targetable proteins. This screen revealed both shared and lineage-specific targets, including several proteins previously considered undruggable, such as transcription factors. Notably, some protein showed mutation-specific engagement by COUPLrs, suggesting potential to selectively target oncogenic variants resistant to existing therapies.Collectively, our work establishes COUPLrs as powerful tools for modulating protein-protein interactions. By integrating covalent chemistry with proteomic profiling, we delineated protein interactions stabilized or disrupted by COUPLrs. These findings open new avenues for therapeutic development against previously inaccessible targets in cancer biology.", "source_company": "Massachusetts General Hospital", "source_org_type": "医院", "row_number": 460, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "TBI-001", "company": "Henry Ford Health + Michigan State University Health Sciences", "org_type": "医院", "target": "TRIB2", "modality": "inhibitor", "importance_level": "中", "total_score": 59, "institution_score": 35, "track_score": 75, "milestone_score": 80, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "TBI-001为靶向TRIB2的口服小分子抑制剂，可诱导TRIB2降解并抑制下游NEPC相关信号，在耐药神经内分泌前列腺癌模型中显示显著肿瘤消退。该项目来自医院+大学合作机构，处于preclinical后期且in vivo疗效明确，但非头部药企导致机构分较低，TRIB2作为新兴靶点在前列腺癌耐药领域有潜力，总分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8793", "id": "NFXM_5wBX1NQZOEH-LO6", "source_drug_name": "TBI-001", "title": "Discovery of potent and selective TRIB2 inhibitors with therapeutic efficacy in therapy-resistant neuroendocrine prostate cancer<!--EndFragment-->", "abstract_text": "Background: Lineage plasticity and therapy resistance remain major challenges in advanced prostate cancer, where a subset of tumors evade androgen receptor (AR)-targeted therapy and acquire neuroendocrine (NE) features. Neuroendocrine prostate cancer (NEPC), whether arising de novo or following antiandrogen treatment, is highly aggressive and lacks effective targeted therapies. We previously identified the pseudokinase TRIB2 as a critical regulator of enzalutamide resistance, lineage plasticity, and tumor survival, establishing it as a potential therapeutic target. However, no TRIB2 inhibitors are currently available for clinical use, underscoring the need for therapeutic development.\nMethods: Using structure-guided in-silico modeling, cell-based screening, and biochemical validation, we identified and optimized TRIB2-targeting small molecules. The lead compound, TBI-001, was evaluated for target engagement, specificity, and functional efficacy. Downstream signaling, phenotypic changes, viability, and apoptosis were evaluated in antiandrogen-resistant and NEPC cell models, as well as engineered cells with TRIB2 overexpression (e.g., LNCaP-TRIB2, RWPE1-TRIB2) using western blotting, IHC, and functional assays. Drug metabolism and pharmacokinetics were examined in preclinical models.\nResults: TBI-001 is a potent and bioavailable TRIB2 inhibitor that directly binds TRIB2, induces its protein degradation, and suppresses downstream survival signaling, including pAKT and BCL2. TBI-001 broadly inhibited TRIB2-regulated NE and lineage-plasticity programs, including epigenetic and transcriptional regulators (EZH2, BRD4, SOX2, NMYC), canonical NE transcription factors (ASCL1, BRN2), the NE antigen DLL3, and the effector PEG10. Importantly, TBI-001 reduced CD56 (NCAM1), a NEPC surface marker linked to lineage plasticity, metastasis, and immune evasion, as well as the immune-modulatory molecule B7-H3 (CD276), indicating effects on both NE differentiation and immune-evasive signaling. Functionally, TBI-001 markedly reduced viability and induced apoptosis in antiandrogen-resistant prostate cancer cell lines and NEPC models (NCI-H660, LASCPC-01), while demonstrating limited effects in control epithelial cells. In vivo, TBI-001 treatment led to significant tumor regression in therapy-resistant NEPC xenograft models, decreased NE marker expression, and showed no observable toxicity. Metabolic profiling in human hepatocytes confirmed efficient hepatic metabolism and favorable stability.\nConclusions: These findings establish that pharmacologic targeting of TRIB2 with TBI-001 disrupts oncogenic signaling and neuroendocrine programs that drive aggressive prostate cancer behavior. TBI-001 demonstrates strong anti-tumor activity, favorable tolerability, and promising pharmacologic profile, supporting its advancement toward clinical development as TRIB2-targeted therapy for advanced, therapy-resistant prostate cancer.", "source_company": "Henry Ford Health + Michigan State University Health Sciences", "source_org_type": "医院", "row_number": 688, "target_meta": "TRIB2", "MOA_meta": "抑制剂"}, {"drug_name": "SJEFS-S19 LV", "company": "St. Jude Children's Research Hospital", "org_type": "医院", "target": "RPS19", "modality": "CAR", "importance_level": "中", "total_score": 59, "institution_score": 45, "track_score": 75, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "SJEFS-S19 LV为编码RPS19的慢病毒载体，用于Diamond-Blackfan贫血的基因治疗，靶向恢复RPS19功能。St. Jude作为顶级儿科研究医院有一定实力，但非商业药企导致机构分较低，基因治疗赛道仍具热度且preclinical数据扎实，总分处于中位水平。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1790", "id": "JVXM_5wBX1NQZOEH-LS6", "source_drug_name": "SJEFS-S19 LV", "title": "Development of RT-dPCR-based functional release assays for the RPS19 gene therapy for Diamond-Blackfan anemia", "abstract_text": "Diamond-Blackfan Anemia (DBA) is a congenital ribosomopathy primarily caused by heterozygous loss-of-function mutations in RPS19, a key component of the 40S ribosomal subunit. RPS19 haploinsufficiency disrupts ribosome biogenesis, triggers p53-dependent cellular stress, and impairs the survival of erythroid progenitor cells. Beyond severe anemia, DBA patients exhibit a slightly elevated risk of hematologic and solid malignancies, highlighting a direct link between ribosomal dysfunction and cancer predisposition. Currently, the only curative approach for DBA is allogeneic bone marrow transplantation which is associated with risk of graft failure and graft-versus-host disease. Gene addition using a third-generation self-inactivating lentiviral vector encoding RPS19 (SJEFS-S19 LV) offers a promising strategy to restore functional RPS19 expression in patient hematopoietic stem and progenitor cells (HSPCs) while maintaining genomic safety and avoiding immune toxicities. Preclinical studies demonstrate that SJEFS-S19 LV effectively corrects erythropoietic defects, restores pre-rRNA processing, and generates a polyclonal, genomically stable population of HSPCs. LVs predominantly integrate into open chromatin regions associated with active transcription. To ensure product quality and functional integrity, we developed a reverse transcription digital PCR (RT-dPCR)-based release assay designed to detect and quantify RPS19 transcript originating specifically from the integrated lentiviral vector following transduction. This approach partitions nucleic acid samples into thousands of micro-reactions, enabling absolute quantification with minimal amplification bias. For determining the RPS19 LV functionality, HEK293 RPS19-heterozygous knockout cells were transduced at varying multiplicities of infection (MOI), and total RNA was extracted for one-step RT-dPCR targeting the LV-derived codon-optimized RPS19 sequence. Increasing MOI correlated with higher normalized RPS19 transcript copies per ng genomic DNA, confirming successful vector integration and expression. This assay provides a robust, quantitative measure of functional gene expression, supporting critical quality attribute assessment of SJEFS-S19 LV. This functional assay concept is being translated into a critical release assay for the RPS19 Gene Therapy Drug Product in transduced CD34+ cells. Overall, this assay platform enables precise assessment of vector performance and provides a framework for translating LV gene therapy toward clinical applications in DBA patients, with potential implications for understanding how restoration of ribosomal protein function may impact oncogenic susceptibility.", "source_company": "St. Jude Children's Research Hospital", "source_org_type": "医院", "row_number": 857, "target_meta": "RPS19", "MOA_meta": "其他"}, {"drug_name": "anti-CD44v9-MMAF", "company": "University of Hawai‘i Cancer Center", "org_type": "研究机构", "target": "CD44v9", "modality": "ADC", "importance_level": "中", "total_score": 59, "institution_score": 35, "track_score": 85, "milestone_score": 70, "field_heat_score": 75, "bonus_score": 3, "brief_reason": "靶向CD44v9的ADC在晚期乳腺癌尤其是三阴性和T-DXd耐药模型中显示出良好体外和体内抗肿瘤活性。机构为大学研究中心得分较低，但ADC赛道+CD44v9在难治性乳腺癌中的潜力使整体重要性处于中等水平。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4044", "id": "YlXM_5wBX1NQZOEH-LS6", "source_drug_name": "anti-CD44v9-MMAF", "title": "CD44v9-targeted antibody-drug conjugate as a novel therapy for advanced breast cancer", "abstract_text": "Background: Aggressive breast cancers, including triple-negative and inflammatory subtypes, urgently require novel therapeutic strategies. Antibody-drug conjugates (ADCs) have shown improved outcomes in HER2- and TROP2-positive breast tumors; however, the heterogeneous expression of target antigens and the development of acquired resistance often limit their long-term clinical benefit. Identifying tumor-selective antigens that remain expressed in advanced and ADC-refractory breast cancers is critical. CD44 variant isoform 9 (CD44v9), a splice variant of the CD44 family, is highly expressed in aggressive breast cancers but largely absent in normal tissues. Functionally, CD44v9 promotes cancer stemness, oxidative stress adaptation, and therapeutic resistance, making it a promising ADC target.\nMethods: CD44v9 expression was evaluated in human breast cancer cell lines, patient-derived xenografts, and tumor specimens by immunohistochemistry, with comparison to normal tissues. A chimeric anti-CD44v9 monoclonal antibody (clone SUM24.1) was conjugated to the microtubule inhibitor monomethyl auristatin F (MMAF). Binding, internalization, and cytotoxicity were assessed in triple-negative, inflammatory, and ADC-resistant breast cancer models. Antitumor efficacy was tested in TNBC xenografts and T-DXd-resistant breast cancer models.\nResults: CD44v9 was abundantly expressed across TNBC models and largely absent from a broad panel of normal human tissues, including peripheral blood mononuclear cells. The anti-CD44v9 antibody demonstrated strong binding to its target and efficient internalization, supporting selective MMAF delivery to cancer cells. Anti-CD44v9-MMAF induced potent, target-dependent cytotoxicity in vitro (p < 0.0001) and significant tumor growth inhibition (TGI) in TNBC xenografts (SUM149: 50% TGI at 0.5 mg/kg, 90% TGI at 2 mg/kg; HCC1806: 50% TGI at 0.5 mg/kg, 95% TGI at 2 mg/kg; p < 0.0001), accompanied by increased apoptosis, reduced proliferation, and minimal systemic toxicity. Notably, CD44v9 expression persisted in breast cancer cells resistant to trastuzumab deruxtecan (T-DXd) and sacituzumab govitecan, and these models remained sensitive to CD44v9-directed MMAF therapy in vitro (p < 0.0001) and in SUM190-T-DXd-R xenografts (70% TGI at 2 mg/kg; p < 0.0001), demonstrating CD44v9’s therapeutic independence from HER2 and TROP2 pathways.\nConclusion: CD44v9 is a tumor-specific, biologically meaningful target for ADC development in advanced breast cancer. The preclinical efficacy and selectivity of anti-CD44v9-MMAF highlight its potential as a next-generation therapy for patients with CD44v9-positive, treatment-refractory breast cancers.", "source_company": "University of Hawai‘i Cancer Center", "source_org_type": "研究机构", "row_number": 898, "target_meta": "CD44v9", "MOA_meta": "抗体偶联药物"}, {"drug_name": "antibodies targeting a tumor-associated immunomodulatory protein", "company": "Mimabs", "org_type": "公司", "target": "未披露", "modality": "inhibitor", "importance_level": "中", "total_score": 59, "institution_score": 45, "track_score": 75, "milestone_score": 60, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "靶点为肿瘤相关免疫调节蛋白（具体未披露），采用单B细胞快速筛选平台发现具有高亲和力、特异性、阻断及内化功能的抗体，适用于免疫调节剂或ADC开发。Mimabs作为小型欧洲抗体CRO/初创biotech机构非头部，技术平台先进且有ADC潜力，但整体仍处早期技术展示阶段，故综合评为中重要。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5612", "id": "rVXM_5wBX1NQZOEH-LS6", "source_drug_name": "antibodies targeting a tumor-associated immunomodulatory protein", "title": "Implementation of single B-cell screening to select antibodies in one day based on affinity and multiple binding properties", "abstract_text": "Purpose: The aim of this study was to establish a rapid and de-risked workflow enabling the selection and functional characterization of antibody-secreting plasma cells based on function, within a single day to streamline therapeutic antibody discovery.\nMethods: BALB/c and transgenic mice carrying human VH/Vκ repertoires were immunized with the recombinant extracellular domain of a tumor-associated immunomodulatory protein. High-titer animals were screened on the Bruker Beacon microfluidic platform, which isolates single plasma cells in nanowells and enables multiplexed assessment of their secreted antibodies. First, beads coated with the ligand and a soluble target conjugated to a fluorochrome allowed simultaneous evaluation of binding affinity and neutralizing capacity. In a second step, beads coated with a structural analog of the target were used to assess the cross-reactivity. Plasma cells producing antibodies of interest were exported for VH/VL amplification, sequencing, and cloning into a mammalian expression vector. Recombinant antibodies were produced and purified for in-depth characterization. Binding affinity and functional blocking were confirmed by biolayer interferometry, while internalization kinetics were quantified using a lanthanide-based pH-sensitive probe. In-silico sequence analysis and structural modeling were applied to identify potential liabilities and exclude clones at risk of poor developability.\nResults: The single-day screening workflow enabled high resolution discrimination of plasma cells based on fine differences in affinity and functional binding properties. 215 clones displayed high specificity for the target with no detectable cross-reactivity to analogs and effectively blocked target-ligand interactions. BLI confirmed the accuracy of the phenotypes identified on the microfluidic platform. Internalization assays identified a subset of antibodies with rapid uptake properties compatible with ADC development and computational filtering further refined the panel of antibodies of therapeutic interest by discarding clones with predicted structural liabilities or developability risks.\nConclusions: This integrated and accelerated workflow provides high-resolution functional screening of antibody-secreting plasma cells in a single experiment. By combining affinity ranking, specificity and cross-reactivity assessment, neutralization, internalization profiling, and developability evaluation, our antibody discovery process efficiently yields diverse and high-value therapeutic antibody leads with strong potential for development as immunomodulators or ADC candidates.", "source_company": "Mimabs", "source_org_type": "公司", "row_number": 958, "target_meta": "not available", "MOA_meta": "抑制剂"}, {"drug_name": "a first-in-class antagomir therapeutic", "company": "TransCode Therapeutics", "org_type": "公司", "target": "miR-10b", "modality": "antagomir", "importance_level": "中", "total_score": 59, "institution_score": 45, "track_score": 75, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "药物为首创antagomir，靶向miR-10b抑制转移相关通路，针对晚期实体瘤转移；TransCode为小型biotech公司，赛道为新兴RNA抗转移治疗且已进入Phase 1并完成，具备一定临床进展。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/12104", "id": "Up7M_5wBZznHJdnt_W3O", "source_drug_name": "a first-in-class antagomir therapeutic", "title": "Phase 1 clinical trial of a first-in-class antagomir therapeutic against advanced solid tumors", "abstract_text": "Abstract is embargoed at this time.", "source_company": "TransCode Therapeutics", "source_org_type": "公司", "row_number": 1005, "target_meta": "miR-10b", "MOA_meta": "antagomir"}, {"drug_name": "dual PROTAC degrader of SMARCA2/4", "company": "University of Michigan", "org_type": "大学", "target": "SMARCA2/4", "modality": "PROTAC", "importance_level": "中", "total_score": 59, "institution_score": 35, "track_score": 85, "milestone_score": 65, "field_heat_score": 75, "bonus_score": 3, "brief_reason": "该dual PROTAC靶向SMARCA2/4，通过破坏mSWI/SNF复合物显著抑制ER+及ESR1突变乳腺癌的ER信号和肿瘤生长。大学机构分数较低，但PROTAC热门赛道+乳腺癌内分泌耐药未满足需求+PDX模型较强活性使其整体重要性处于中等水平。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8577", "id": "ip7M_5wBZznHJdnt_W7P", "source_drug_name": "dual PROTAC degrader of SMARCA2/4", "title": "Investigating the intrinsic epigenetic dependencies of estrogen receptor positive and ESR1 mutant breast cancer", "abstract_text": "Background: Estrogen receptor alpha (ERα) is a nuclear steroid hormone receptor that regulates transcription through DNA binding. ER is a lineage defining transcription factor (TF) that drives approximately 70% of breast cancer (BC) cases expressing the receptor. Aromatase inhibitor or selective estrogen receptor modulator treatment are first-line endocrine therapies for the treatment of ER+ BC, and they function by disrupting ligand availability or antagonizing ER, respectively. Activating mutations in ESR1, the gene encoding ERα, are enriched in approximately 25% of metastatic cases. ESR1 mutations lock ER in an active conformation, conferring ligand-independent signaling, endocrine therapy resistance, and increased proliferative capacity. Both wild-type and mutant ER primarily act through enhancer elements rather than promoters, relying on a network of transcriptional co-factors and chromatin remodeling complexes to facilitate enhancer accessibility. Targeting these epigenetic dependencies represents a promising therapeutic strategy. The mammalian SWI/SNF (mSWI/SNF) chromatin remodeling complex interacts with ER-associated transcription factors, including FOXA1, and supports enhancer activity and ER recruitment. Thus, disrupting mSWI/SNF function may impair ER-driven transcriptional programs in ER+ BC.\nMethods: mSWI/SNF activity was perturbed using either a dual PROTAC degrader of SMARCA2/4 or a selective SMARCA2/4 ATPase inhibitor. Pharmacological effect was assessed in a variety of preclinical models of ER+ and ESR1 mutant BC including cell lines and patient-derived xenografts (PDX). Mechanisms of action of ER signaling disruption and mSWI/SNF dependence were investigated using multi-omics techniques such as RNA-seq, ATAC-seq, ChIP-seq, and RIME.\nResults: We showed that ER+ BC cell lines are preferentially sensitive to mSWI/SNF complex inactivation at nanomolar concentrations of both compounds. We also demonstrated significant anti-tumor activity in both ER wild type and mutant PDX models. This anti-proliferative phenotype is shown to be driven by ER signaling axis disruption, with key downstream targets like c-Myc and CCND1 being downregulated. Mechanistically, we demonstrate these effects are mediated by reduced chromatin accessibility at enhancer regions, changes in the FOXA1 and ER cistromes, and a disruption of the ER interactome.\nConclusions: We establish the mSWI/SNF complex as a critical epigenetic dependency that sustains ER transcriptional activity in ER+ BC. Therapeutic targeting of SMARCA2/4 effectively disrupts enhancer function, impairs ER signaling, and suppresses tumor growth. mSWI/SNF-directed therapies therefore represent a promising strategy for advanced and endocrine-resistant ER+ breast cancers.", "source_company": "University of Michigan", "source_org_type": "大学", "row_number": 1217, "target_meta": "SMARCA2,SMARCA4", "MOA_meta": "PROTAC"}, {"drug_name": "anti-VISTA×MSLN bispecific antibody", "company": "Seoul National University", "org_type": "大学", "target": "VISTA×MSLN", "modality": "bispecific antibody", "importance_level": "中", "total_score": 58.5, "institution_score": 35, "track_score": 85, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "药物为靶向VISTA（免疫检查点）和MSLN（肿瘤相关抗原）的双特异性抗体，针对上皮型恶性胸膜间皮瘤的生物标志物导向策略，具有双靶点协同机制潜力。机构为大学导致institution_score较低，但双抗+免疫细胞因子+ADC多模态扩展属于热门赛道且preclinical显示体内疗效和TME重塑，综合热度和里程碑中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4518", "id": "G1XM_5wBX1NQZOEH-LK6", "source_drug_name": "anti-VISTA×MSLN bispecific antibody", "title": "VISTA×MSLN bispecific antibody-directed therapies as a biomarker-guided strategy for epithelioid malignant pleural mesothelioma", "abstract_text": "Background Malignant pleural mesothelioma (MPM) is a rare, lethal cancer largely linked to asbestos exposure, with a 5-year overall survival <20%. Until the approval of nivolumab plus ipilimumab (CheckMate 743), platinum-based chemotherapy was the only systemic standard of care. The epithelioid subtype (~70% of cases) of MPM derives limited benefit from current ICIs, underscoring the need for biomarker-guided therapies. We identified co-expression of the immune checkpoint V-domain Ig suppressor of T-cell activation (VISTA) and the tumor-associated antigen mesothelin (MSLN) in epithelioid MPM and validated this axis by scRNA-seq, which demonstrated concordant VISTA and MSLN transcription within malignant epithelioid clusters. Based on this biomarker pair, we engineered an anti-VISTA×MSLN bispecific antibody (BsAb) and explored multiple modalities, including an IFN-β mutein immunocytokine and bispecific ADC concepts.\nMethod Anti-VISTA×MSLN BsAb formats were designed and screened for optimal binding/cell-surface coverage on VISTA/MSLN co-expressing cells. A stability/production/PK-enhanced IFN-β mutein relative to recombinant IFN-β was fused to the BsAb to generate a trispecific immunocytokine. In vitro binding, internalization, and effector assays were performed in human MPM cell lines. In vivo antitumor activity and TME modulation were tested in xenografts and a syngeneic mouse model; a subset used human IFNAR1/2 knock-in (hIFNAR1/2-KI) mice. To assess suitability for payload delivery, we analyzed antigen-dependent internalization and early bispecific ADC feasibility in vitro.\nResults scRNA-seq confirmed VISTA/MSLN co-expression in malignant epithelioid populations, supporting VISTA×MSLN as a therapeutic axis. The anti-VISTAxMSLN BsAb showed enhanced binding to dual-positive cells relative to the parental monospecific antibodies and efficient, antigen-driven internalization. The trispecific immunocytokine retained BsAb targeting and induced type I IFN-dependent tumor-cell killing and immune activation in vitro. In vivo, it produced significant antitumor activity in MPM models, including in hIFNAR1/2-KI mice, and remodeled the TME consistent with enhanced antitumor immunity. Internalization/trafficking supported feasibility of developing anti-VISTA×MSLN BsAb ADCs as an additional therapeutic modality.\nConclusion VISTA/MSLN co-expression defines a biomarker-guided therapeutic axis in epithelioid MPM. The engineered anti-VISTAxMSLN BsAb is a versatile scaffold enabling multiple modalities— including an IFN-β mutein immunocytokine with in vivo efficacy and TME reprogramming—and exhibits internalization compatible with bispecific ADC development. Collectively, these findings support anti-VISTA×MSLN-based therapeutics as promising preclinical candidates for epithelioid MPM.", "source_company": "Seoul National University", "source_org_type": "大学", "row_number": 24, "target_meta": "VISTA,MSLN", "MOA_meta": "双特异性抗体"}, {"drug_name": "α3β4-targeted DISCO CAR T cells", "company": "Children's Hospital Of Philadelphia", "org_type": "医院", "target": "α3β4 nicotinic acetylcholine receptor", "modality": "CAR", "importance_level": "中", "total_score": 58.5, "institution_score": 35, "track_score": 75, "milestone_score": 75, "field_heat_score": 70, "bonus_score": 5, "brief_reason": "靶向新型α3β4烟碱型乙酰胆碱受体亚基复合物（需双亚基同时识别），采用DISCO CAR设计实现高选择性，针对神经母细胞瘤等实体瘤显示强效PDX模型体内疗效及视网膜母细胞瘤模型单剂显著控制肿瘤。机构为顶级儿童医院但非商业药企，赛道为热门CAR实体瘤新靶点+创新构型+preclinical强数据，综合潜力中等偏上。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4309", "id": "W1XM_5wBX1NQZOEH-LK6", "source_drug_name": "α3β4-targeted DISCO CAR T cells", "title": "Selective targeting of the α3β4 nicotinic acetylcholine receptor by DISCO (dual interacting subunit complex) CAR T cells", "abstract_text": "Developing effective chimeric antigen receptor (CAR) T cell therapies for pediatric solid tumors requires discovery of highly tumor-selective cell surface molecules. Using a multimodal immunotherapeutic target discovery platform, we identified a receptor composed of the nicotinic acetylcholine receptor subunits α3 and β4 as a new previously unrecognized immunotherapeutic target in neuroblastoma. CHRNA3 (α3) and CHRNB4 (β4) are robustly differentially overexpressed in neuroblastoma compared with normal tissues, driven by a super-enhancer upstream of the CHRNA3/B4 locus on chromosome 15q25 that is occupied by neuroblastoma core regulatory transcription factors and physically engages both promoters. Neuroblastoma cells exhibit abundant α3 and β4 protein, which bind and assemble into a stabilized α3β4 complex displayed at high levels on the neuroblastoma cell surface. Functionally, genetic depletion of α3 also reduced β4 levels, induced mesenchymal cell state-associated marker expression, and increased proliferation and invasion in neuroblastoma cell line models. To therapeutically exploit this tumor-restricted α3β4 receptor expression, we engineered Dual Interacting Subunit COmplex (DISCO)-specific single chain variable fragments (scFvs) designed to recognize an epitope requiring simultaneous engagement of both α3 and β4 subunits of the α3β4 cell surface receptor. DISCO CAR T cells generated from these scFvs bound selectively to and were potently activated by the α3β4 receptor, but not either subunit individually. α3β4-targeted DISCO CAR T cells demonstrated potent and selective cytotoxicity across diverse neuroblastoma cell lines and three patient-derived xenograft (PDXs) models, significantly extending the survival of mice harboring PDXs with a range of α3 and β4 expression (P < 0.05). Beyond neuroblastoma, CHRNA3 and CHRNB4 are also highly expressed in small cell lung cancer (SCLC) and retinoblastoma, among several other tumors. The identical super-enhancer is associated with high levels of CHRNA3 and CHRNB4 in SCLC, suggesting similar mechanisms of tumor-driven overexpression. In an intraocular retinoblastoma xenograft model, a single intravitreal dose of α3β4-redirected DISCO CAR T cells achieved marked tumor control and significantly extended ocular survival (P = 0.0015), collectively showing disease-relevance and targetability beyond neuroblastoma. Together, these findings broaden the repertoire of actionable CAR T cell targets in pediatric and adult solid tumors by validating the α3β4 receptor, and more broadly the nicotinic acetylcholine receptor family, as bona fide immunotherapeutic candidates. Moreover, these studies demonstrate that CARs can be designed to recognize disease-relevant subunit configurations within multidomain surface receptors.", "source_company": "Children's Hospital Of Philadelphia", "source_org_type": "医院", "row_number": 34, "target_meta": "α3β4 receptor", "MOA_meta": "其他"}, {"drug_name": "Nectin-4-specific CAR-NK cells", "company": "University of Chicago", "org_type": "大学", "target": "Nectin-4", "modality": "CAR", "importance_level": "中", "total_score": 58.5, "institution_score": 35, "track_score": 85, "milestone_score": 65, "field_heat_score": 75, "bonus_score": 0, "brief_reason": "靶向Nectin-4的CAR-NK细胞在体外和体内模型中显示对膀胱癌的显著抗肿瘤活性。机构为大学得分较低，但CAR-NK赛道热度高、膀胱癌未满足需求明显、preclinical数据较为扎实。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9378", "id": "1lXM_5wBX1NQZOEH-LK6", "source_drug_name": "Nectin-4-specific CAR-NK cells", "title": "Nectin-4-targeted CAR-NK cells exhibit potent antitumor activity against bladder cancer", "abstract_text": "Background: Bladder cancer (BC) remains a major clinical challenge due to frequent recurrence and limited durable responses to current therapies such as Bacillus Calmette-Guérin (BCG) immunotherapy and cisplatin-based chemotherapy. Natural Killer (NK) cell therapy has recently emerged as a promising immunotherapeutic approach, particularly when combined with Chimeric Antigen Receptor (CAR) technology to enhance tumor recognition and cytotoxicity. Nectin-4, an adhesion molecule highly expressed in BC, represents a strong therapeutic target for CAR-engineered NK cells. In this study, we aimed to target bladder cancer using Nectin-4-specific CAR-NK cells.\nMethods: Nectin-4-specific CAR-NK cells were generated via lentiviral transduction, and CAR expression was confirmed by fluorescence microscopy. The cytotoxic activity of CAR-NK and unmodified NK cells was evaluated against Nectin-4-positive (SW780) and Nectin-4-negative (T24) bladder cancer cell lines using LDH release and CCK-8 viability assays at early time points. A 3D spheroid model was used to assess CAR-NK cell attachment, infiltration, and long-term cytotoxicity. Gene expression profiling following co-culture was performed to evaluate activation and apoptosis-related pathways. An in vivo xenograft model was used to validate the in vitro findings.\nResults: Nectin-4 CAR-NK cells demonstrated significantly enhanced cytotoxicity compared with parental NK cells within 4 hours of co-culture with SW780 cells, as assessed by LDH and CCK-8 assays. In 3D spheroid models, CAR-NK cells showed stronger attachment and affinity for Nectin-4-positive tumor spheroids during short-term co-culture and exhibited higher cytotoxicity after prolonged exposure compared with unmodified NK cells. Gene expression analysis revealed increased activation markers and cytotoxic mediators in CAR-NK cells, along with upregulation of apoptosis-related genes in target tumor cells following treatment.\nConclusions: Engineering NK cells with a Nectin-4-specific CAR markedly enhances their ability to recognize and eliminate Nectin-4-positive bladder cancer cells. These findings support the potential of Nectin-4 CAR-NK therapy as a targeted immunotherapeutic strategy for bladder cancer. Future development of multi-targeted CAR-NK constructs designed to modulate the tumor microenvironment may further improve efficacy and overcome immune resistance.", "source_company": "University of Chicago", "source_org_type": "大学", "row_number": 46, "target_meta": "NECTIN4", "MOA_meta": "其他"}, {"drug_name": "MAb51-31-ADC", "company": "MedAbome, Inc.", "org_type": "公司", "target": "Integrin α/β", "modality": "ADC", "importance_level": "中", "total_score": 58.5, "institution_score": 45, "track_score": 75, "milestone_score": 70, "field_heat_score": 65, "bonus_score": 3, "brief_reason": "靶点为肿瘤特异构象表位的Integrin α/β，ADC modality通过肿瘤特异性结合实现强效杀伤并减少脱靶。MedAbome为美国preclinical stage小型biotech，非头部机构但ADC热门赛道+CDX模型中单剂完全肿瘤消退的强效preclinical数据，综合热度中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5404", "id": "6J7M_5wBZznHJdnt_W3O", "source_drug_name": "MAb51-31-ADC", "title": "Preclinical efficacy of a first-in-class anti-Integrin α/β ADC in hard-to-treat solid tumors", "abstract_text": "Integrin (ITG) α/β is a heterodimeric type I transmembrane glycoprotein composed of one α and one β integrin subunit. It mediates cell-cell and cell-extracellular matrix (ECM) interactions and elicits subsequent signaling cascades that regulate cell adhesion, motility, proliferation, survival, and gene expression. The aberrant overexpression of ITGα/β has been observed across a variety of solid tumors, and it supports cancer progression and metastasis, suggesting that it may serve as a potential therapeutic target. Using our proprietary live-cell immunization (LC-I) and high-throughput screening (LC-HTS) platforms, we generated and developed MAb51-31, an anti-ITGα/β monoclonal antibody (mAb), which selectively recognizes a tumor-restricted conformational epitope of ITGα/β. MAb51-31 exhibited no cross-reactivity with normal cells or tissues. Both the chimeric and humanized versions of MAb51-31 displayed high binding affinity to recombinant ITGα/β (KD ≈ 1.4 nM). MAb51-31-cAb, engineered with two point-mutations in each Fc region, was conjugated to MMAE via an MC-Vc-PAB linker to generate MAb51-31-ADC (DAR4). MAb51-31-ADC demonstrated potent antiproliferative effects in vitro, with cytotoxicity correlating with its internalization efficiency across various solid tumor cell lines. In cell line-derived xenograft (CDX) models of triple-negative breast cancer (TNBC), non-small cell lung cancer (NSCLC), gastric cancer (GC), and other solid tumors, a single intraperitoneal (i.p.) dose of MAb51-31-ADC at 4, 7, or 10 mg/kg effectively inhibited tumor growth, resulting in complete tumor regression within 24~30 days post-treatment. Initial toxicology assessments indicated that MAb51-31-ADC was well tolerated, with no notable safety concerns observed. MAb51-31-ADC is a promising therapeutic candidate for treating solid tumors, with selective recognition of a tumor-specific ITGα/β epitope potentially enabling strong antitumor efficacy and reduced off-target effects. Ongoing studies include evaluation of MAb51-31-ADC in patient-derived xenograft (PDX) models of gastrointestinal (GI) cancers, as well as retrospective analyses of target expression in tumor samples, to further support its clinical development.", "source_company": "MedAbome, Inc.", "source_org_type": "公司", "row_number": 141, "target_meta": "integrin", "MOA_meta": "抗体偶联药物"}, {"drug_name": "PC-13", "company": "Chinese Academy of Medical Sciences and Peking Union Medical College", "org_type": "研究机构", "target": "PI3K and CDK4/6", "modality": "inhibitor", "importance_level": "中", "total_score": 58.5, "institution_score": 45, "track_score": 75, "milestone_score": 60, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "PC-13为新型PI3K与CDK4/6双靶点抑制剂，针对乳腺癌具有潜在首创性；研发机构为中国顶级研究机构但非头部药企，赛道双靶点组合在乳腺癌领域有较高热度但仍处临床前阶段。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6430", "id": "Z1XM_5wBX1NQZOEH-LO6", "source_drug_name": "PC-13", "title": "Discovery and development of a novel PI3K-CDK4/6 dual inhibitor PC-13 for the treatment of breast cancer", "abstract_text": "Breast cancer continues to be a major cause of cancer-associated mortality globally, underscoring the urgent need for innovative therapeutic strategies. In this study, we report the discovery and preclinical characterization of PC-13, a potential first-in-class dual inhibitor targeting both PI3K and CDK4/6. PC-13 demonstrates nanomolar-level potency against PI3K and CDK4/6 kinases, high selectivity across a broad panel of kinases, and potent antiproliferative effects in multiple breast cancer cell lines. Furthermore, PC-13 exhibits reasonable pharmacokinetic properties and achieves significant tumor growth suppression in a T47D xenograft model, with efficacy comparable to the Palbociclib-Buparlisib combination regimen, while maintaining a promising safety profile. Our findings highlight the potential of concurrent PI3K and CDK4/6 inhibition as a novel and effective therapeutic approach for breast cancer, supporting further development of PC-13 as a clinical candidate.", "source_company": "Chinese Academy of Medical Sciences and Peking Union Medical College", "source_org_type": "研究机构", "row_number": 144, "target_meta": "PI3K,CDK6,CDK4", "MOA_meta": "抑制剂"}, {"drug_name": "A9", "company": "University of Florida", "org_type": "大学", "target": "IKKβ and NR4A1", "modality": "PROTAC", "importance_level": "中", "total_score": 58.5, "institution_score": 35, "track_score": 85, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "A9为celastrol-based PROTAC，同时降解IKKβ和NR4A1双靶点，提供新型AML治疗策略，避免IKKβ抑制剂的中性粒细胞增多副作用。大学机构得分较低，但PROTAC热门赛道+双靶点协同+体内疗效验证使整体潜力中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5705", "id": "-57M_5wBZznHJdnt_W3O", "source_drug_name": "A9", "title": "Dual targeting of IKKβ and NR4A1 for AML therapy", "abstract_text": "Acute myeloid leukemia (AML) is a common aggressive blood cancer with a lethality rate among the highest of all leukemia subtypes. Cure rates of available therapeutic options are very low, underscoring an urgent need to develop more effective drugs. Here we identify IKKβ and NR4A1 as two closely related, clinically meaningful drivers of AML progression, and develop a proteolysis targeting chimera (PROTAC) drug that degrades both the proteins. IKKβ and the downstream NF-κB signaling are aberrantly activated in around 40% AML patients. However, IKKβ inhibitors exhibit serious side effects such as neutrophilia, limiting their therapeutic development. As opposed to the previously reported AML-suppressive role, we found that NR4A1 can also promote AML pathogenesis in different contexts. Moreover, IKKβ and NR4A1 were found to be highly expressed in AMLs associated with poor clinical outcomes, positively regulate each other’s expression, and synergize to maintain AML cell viability. We designed, synthesized, and validated an array of celastrol-based PROTACs as celastrol binds to both IKKβ and NR4A1, and identified one lead PROTAC, A9, that effectively kills several AML cell lines and primary human AML cells. Mechanistically, A9-induced AML cell killing was found to be dependent on CRBN E3 ligase-mediated dual degradation of IKKβ and NR4A1. In vivo, A9 attenuated AML disease progression in a clinically relevant KMT2A::MLLT3 mouse model and didn’t induce neutrophilia. Our results reveal a potentially novel strategy to treat intractable and aggressive AMLs in the clinic.", "source_company": "University of Florida", "source_org_type": "大学", "row_number": 168, "target_meta": "IKKβ,NR4A1", "MOA_meta": "PROTAC"}, {"drug_name": "CT11a1-ADC", "company": "Nordic Bioscience", "org_type": "公司", "target": "type XI collagen", "modality": "ADC", "importance_level": "中", "total_score": 58.5, "institution_score": 55, "track_score": 75, "milestone_score": 45, "field_heat_score": 65, "bonus_score": 2, "brief_reason": "CT11a1-ADC靶向肿瘤相关肌成纤维细胞（myCAFs）特异性表达的type XI collagen，通过ADC机制选择性消除CAFs以改善肿瘤微环境药物递送。Nordic Bioscience作为专注ECM生物标志物的专业biotech公司非典型药物研发机构，得分中等；ADC+肿瘤基质靶点赛道热度较高，但仅体外模型显示剂量依赖CAF杀伤，处于早期preclinical阶段，整体重要性中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5738", "id": "V1XM_5wBX1NQZOEH-LO6", "source_drug_name": "CT11a1-ADC", "title": "Targeting type XI collagen to facilitate elimination of cancer-associated fibroblasts?", "abstract_text": "Background: Fibrotic tumors pose a major therapeutic challenge due to the dense stromal barriers formed by myofibroblastic cancer-associated fibroblasts (myCAFs), which increase tissue stiffness and impede drug delivery. These myCAFs are characterized by elevated expression of type XI collagen, a key component of the fibrous cap. Antibody-drug conjugates (ADCs) offer a targeted approach by linking monoclonal antibodies to cytotoxic payloads, enabling selective delivery within the tumor microenvironment. Here, we present a novel ADC-based strategy that targets tumor-associated type XI collagen to selectively eliminate myCAFs. This approach combines CT11a1, an antibody recognizing a tumor-specific type XI collagen epitope, as the delivery vehicle, with PRO-C11, a circulating biomarker of type XI collagen for potential patient selection and treatment monitoring.\nMethods: ELISAs were used to quantify CT11a1 and PRO-C11 collagen epitopes in serum from patients with various cancer types and healthy controls. Pancreatic cancer-associated fibroblasts (CAFs), normal fibroblasts (NFs), and co-cultures of CAFs with pancreatic cancer cells (BxPC3) were cultured in the SiaJ model for 12 days. On day 12, cultures were immunostained with CT11a1 or PRO-C11 antibodies. A CT11a1-ADC was developed and its effect on cell viability was quantified using the Alamar Blue assay.\nResults: Among several tested collagen-based biomarkers, PRO-C11 demonstrated the highest diagnostic accuracy (AUC: 0.99) across all cancer types. In contrast CT11a1 was barely detectable in serum. Immunostaining with the CT11a1 antibody on day 12 of the SiaJ model revealed prominent type XI collagen deposition in wells containing CAFs while minimal to no signal was detected in wells with NFs. In contrast, staining CAFs with the PRO-C11 antibody did not result in any detectable signal, indicating limited accessibility or absence of the PRO-C11 epitope in the extracellular matrix (ECM). Staining of co-cultures with the CT11a1 antibody revealed that type XI collagen is localized in the fibrous cap-like structure positioned between the cancer cells and the fibroblasts. Initial treatments with CT11a1-ADC induced a dose-dependent decrease in CAF viability.\nConclusion: Type XI collagen is specific to myCAFs. The CT11a1 epitope is detectable in the CAF-derived ECM, but not in circulation, whereas the opposite is true for PRO-C11. The developed CT11a1-ADC demonstrates potential as an ADC specifically targeting type XI collagen produced by myCAFs. PRO-C11 may serve as a biomarker to identify patients with high type XI collagen production. Further exploration and validation are ongoing.", "source_company": "Nordic Bioscience", "source_org_type": "公司", "row_number": 237, "target_meta": "COL11", "MOA_meta": "抗体偶联药物"}, {"drug_name": "CD16HSC-NKT cells", "company": "University of California, Los Angeles", "org_type": "大学", "target": "未披露", "modality": "CAR", "importance_level": "中", "total_score": 58.5, "institution_score": 35, "track_score": 85, "milestone_score": 65, "field_heat_score": 80, "bonus_score": 4, "brief_reason": "该产品为工程化干细胞来源的CD16增强型通用NKT细胞，主要通过高亲和力CD16介导ADCC增强mAb疗效，同时具有NKT固有抗肿瘤机制；虽然靶点未明确披露，但 allogeneic off-the-shelf NKT平台结合强大TME重塑能力在细胞治疗热门赛道具潜力，大学机构限制了机构分。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5279", "id": "5VXM_5wBX1NQZOEH-LC5", "source_drug_name": "CD16HSC-NKT cells", "title": "Improvement of monoclonal antibody therapy against cancer through engineering stem cell-derived CD16-enhanced universal NKT cells", "abstract_text": "Monoclonal antibody (mAb)-based immunotherapies have revolutionized cancer treatment, yet their efficacy remains limited in many solid and hematologic malignancies due to insufficient effector cell engagement, tumor antigen loss, and immunosuppressive tumor microenvironments. To overcome these limitations and enhance the therapeutic potential of mAb therapy, we developed an allogeneic invariant natural killer T (NKT) cell platform through hematopoietic stem cell (HSC) engineering and feeder-free in vitro differentiation. Specifically, we introduced an invariant NKT T cell receptor (TCR) and a high-affinity, non-cleavable CD16a (FcγRIIIa) receptor into HSCs, enabling the generation of CD16-enhanced HSC-engineered NKT (CD16HSC-NKT) cells. These cells can be produced at high yield and purity in a scalable, feeder-free culture system. The resulting CD16HSC-NKT cells preserve the hallmark NKT phenotype and exhibit robust cytokine secretion, cytotoxicity, and tumor infiltration capacity. Functionally, CD16HSC-NKT cells mediate potent antibody-dependent cellular cytotoxicity (ADCC) both in vitro and in vivo when combined with tumor-specific monoclonal antibodies, leading to synergistic tumor regression. Beyond direct cytotoxicity, CD16HSC-NKT cells also display multi-targeted antitumor mechanisms, including recognition of CD1d-presented glycolipid antigens and engagement of stress-induced NK ligands. In preclinical tumor models, CD16HSC-NKT cells demonstrated superior persistence and metabolic fitness compared with conventional peripheral blood-derived NKT cells. Importantly, CD16HSC-NKT cells were found to reshape the tumor microenvironment by selectively depleting immunosuppressive tumor-associated macrophages (TAMs) and myeloid-derived suppressor cells (MDSCs), thereby promoting a more pro-inflammatory and immune-permissive milieu. No evidence of graft-versus-host disease, cytokine release syndrome, or long-term organ toxicity was observed, supporting a favorable safety profile. Collectively, our study establishes CD16HSC-NKT cells as a universal, off-the-shelf cellular immunotherapy that can be flexibly paired with diverse monoclonal antibodies to enhance their efficacy, overcome resistance, and expand the therapeutic reach of antibody-based cancer treatment.", "source_company": "University of California, Los Angeles", "source_org_type": "大学", "row_number": 292, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "antibody fragment-drug conjugate", "company": "Antikor Biopharma Ltd", "org_type": "公司", "target": "未披露", "modality": "ADC", "importance_level": "中", "total_score": 58.5, "institution_score": 45, "track_score": 85, "milestone_score": 50, "field_heat_score": 75, "bonus_score": 3, "brief_reason": "采用抗体片段药物偶联物（FDC）技术，针对实体瘤改善渗透性和PK/PD特性，但未披露具体靶点。机构为小型英国biotech，赛道为ADC热门变体且preclinical阶段有SPR优化支持，整体潜力中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6485", "id": "51XM_5wBX1NQZOEH-LC5", "source_drug_name": "antibody fragment-drug conjugate", "title": "ADCs in cancer treatment: SPR-driven insights into discovery and characterization ​", "abstract_text": "Antibody-drug conjugates (ADCs) have significantly advanced cancer therapeutics. Yet their efficacy in solid tumors remain limited due to poor tumor penetration, large molecular size and systemic toxicity. To address these challenges, we present a novel class of antibody fragment-drug conjugate (FDC) engineered for improved pharmacokinetic/pharmacodynamic (PK/PD) profiles and enhanced tumor accessibility. Surface plasmon resonance (SPR) was used to perform high-resolution kinetics and affinity analyses across multiple FDC targets. This approach provided rational candidate selection and optimization of binding kinetics, which supported the development of FDCs with superior tumor penetration and therapeutic potential. Integration of SPR data into the early discovery workflow has proven instrumental in identifying FDCs with optimal kinetic and affinity profiles. In preclinical development, SPR data supported assessment of safety and toxicology of FDCs through precise binding kinetics profiling. SPR data also deepened our understanding of target biology and mitigated development risk by eliminating the need for surrogate antibodies. This integrated approach streamlined the transition from discovery to preclinical evaluation, accelerating therapeutic development. These findings highlight FDCs as promising candidates for solid tumor treatment and provide a strategic path to overcome the limitations of conventional ADCs.", "source_company": "Antikor Biopharma Ltd", "source_org_type": "公司", "row_number": 293, "target_meta": "not available", "MOA_meta": "抗体偶联药物"}, {"drug_name": "JZY3032", "company": "University of Michigan", "org_type": "大学", "target": "AR-p300", "modality": "other", "importance_level": "中", "total_score": 58.5, "institution_score": 35, "track_score": 85, "milestone_score": 65, "field_heat_score": 75, "bonus_score": 8, "brief_reason": "JZY3032为首创DALTAC类分子，通过误导AR-p300生理复合物拓扑结构抑制前列腺癌转录激活，靶点为AR-p300交互界面。大学机构得分较低，但全新机制+高热度转录复合物调控赛道+明确proof-of-concept活性带来较强潜力，总分处于中偏上水平。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8805", "id": "ZFXM_5wBX1NQZOEH-LG5", "source_drug_name": "JZY3032", "title": "Structure-guided design of JZY3032, a dual-engaging DALTAC that miswires AR-p300 in prostate cancer", "abstract_text": "Chemical-induced proximity (CIP) strategies have expanded the therapeutic landscape by modulating protein-protein interactions, yet most current modalities, such as PROTACs and molecular glues—juxtapose non-physiological partners, often yielding variable or unpredictable outcomes. To address this limitation, we developed Domain-ALTeration Chimeras (DALTACs), a mechanistically distinct platform that selectively miswires endogenous protein complexes by enforcing non-productive domain-domain interactions between physiologic partners. Rather than degrading targets or stabilizing native interfaces, DALTACs reconfigure the topology of multi-domain complexes through rational ligand selection and linker engineering. As a proof of concept, we designed JZY3032, the first-in-class AR-p300 DALTAC, to disable the androgen receptor (AR)-p300 transcriptional complex, a critical regulatory node in prostate cancer. Guided by iterative medicinal-chemistry optimization, we conjugated an AR LBD inhibitor to a selective p300 bromodomain inhibitor using a tunable linker optimized for cooperative, simultaneous dual engagement. The resulting construct redirects the physiological AR-p300 interaction surface into a sterically misaligned, non-productive configuration, thereby preventing AR N-terminal domain communication with p300 and suppressing enhancer activation. Mechanistic specificity was confirmed using two negative-control analogs that selectively disrupt AR or p300 binding; both lacked biological activity, demonstrating that dual engagement and domain-reconfiguration are required for DALTAC function. SAR studies revealed that linker length, rigidity, and exit-vector orientation are key determinants of complex miswiring efficiency. Functionally, JZY3032 potently inhibits growth of AR- and p300-co-dependent prostate cancer models while sparing AR-negative lineages, establishing the lineage-selective therapeutic potential arising from engineered domain miswiring. Collectively, these data establish DALTACs as a new class of proximity-based therapeutics capable of disabling oncogenic transcriptional complexes through topology engineering. JZY3032 exemplifies a broadly extensible, modular chemistry platform for rationally designing future DALTAC molecules targeting diverse disease-relevant protein assemblies.", "source_company": "University of Michigan", "source_org_type": "大学", "row_number": 383, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "PSCA-targeted CAR-T cell therapy", "company": "University of Southern California", "org_type": "大学", "target": "PSCA", "modality": "CAR", "importance_level": "中", "total_score": 58.5, "institution_score": 35, "track_score": 85, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "针对PSCA的CAR-T细胞疗法，modality为热门的CAR-T赛道且处于实体瘤临床探索阶段。机构为大学而非头部药企导致institution_score较低，但赛道热度高且已进入Phase 1临床，总分处于中位水平。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9836", "id": "jFXM_5wBX1NQZOEH-LG6", "source_drug_name": "PSCA-targeted CAR-T cell therapy", "title": "Single-cell liquid biopsy profiling in mCRPC receiving PSCA-targeted CAR-T cell therapy", "abstract_text": "Metastatic castration-resistant prostate cancer (mCRPC) represents an aggressive, treatment-refractory stage of prostate cancer with limited treatment options and poor prognosis. Chimeric antigen receptor (CAR)-T cell therapy has demonstrated success in hematological malignancies, but its efficacy in solid tumors is limited by tumor microenvironment (TME) barriers and tumor cell heterogeneity. In this study, we applied a single-cell enrichment-free liquid biopsy platform to monitor disease progression and CAR-T cell response in mCRPC patients enrolled in a Phase 1 clinical trial (NCT03873805). Using fluorescent whole-slide imaging (fWSI), we analyzed peripheral blood (PB) and bone marrow aspirate (BMA) from eight patients (four responders and four nonresponders) collected longitudinally before, during, and after therapy. Two key findings emerged: 1) lymphodepletion mobilized circulating tumor cells (CTCs) from bone marrow into PB, altering compartment-specific cellularity regardless of response, and 2) clearance of clonal CTCs after CAR-T cell infusion occurred in responders but not in nonresponders. Single-cell analyses further revealed that PB and BMA captured distinct CTC subtypes, underscoring the complementary value of both compartments for monitoring. This multi-omic analysis leverages high-resolution single-cell liquid biopsies to characterize circulating rare cells, such as CTCs and their subtypes, to correlate them with clinically observed responses to CAR-T cell therapy in mCRPC.", "source_company": "University of Southern California", "source_org_type": "大学", "row_number": 404, "target_meta": "PSCA", "MOA_meta": "其他"}, {"drug_name": "anti-HER2 CAR mRNA/LNPs", "company": "Peter MacCallum Cancer Centre", "org_type": "医院", "target": "HER2", "modality": "mRNA", "importance_level": "中", "total_score": 58.5, "institution_score": 35, "track_score": 85, "milestone_score": 60, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "药物为anti-HER2 CAR mRNA/LNPs，通过LNP递送实现体内多免疫细胞（髓系、NK、T细胞）CAR工程化，靶点HER2，机制创新在于同时重编程先天与适应性免疫对抗实体瘤。机构为医院/学术中心非头部药企得较低分，但in vivo CAR mRNA+多细胞编程赛道极热、preclinical显示协同多系工程强效肿瘤控制获较高赛道与里程碑分。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5217", "id": "p1XM_5wBX1NQZOEH-LG6", "source_drug_name": "anti-HER2 CAR mRNA/LNPs", "title": "In vivo CAR mRNA engineering of both adaptive and myeloid cells enables potent anti-tumor control of solid cancers", "abstract_text": "Background: In solid tumors, chimeric antigen receptor (CAR) T cell therapies are limited by their inability to overcome poor trafficking, antigen heterogeneity and the immunosuppressive myeloid cells in the tumor microenvironment (TME). Here, we introduce in vivo multi-immune cell programming designed to precisely and simultaneously program multiple immune cell types using a single engineered product. This approach builds on the clinical experience with in vivo CAR-mRNA engineered CAR myeloid cells that created a pro-inflammatory tumor environment. Combining non-targeted and targeted LNP delivery, optimized mRNA, and cell-specific CAR architecture, we endow myeloid cells, NK cells and T cells with tailored effector functions.\nMethods: Anti-HER2 CAR mRNAs optimised for myeloid, NK or T cell signalling were encapsulated in LNPs and delivered intravenously. Anti-tumor efficacy was evaluated in immunocompetent hHER2 transgenic mice bearing syngeneic hHER2-MC38 colon adenocarcinoma tumors.\nResults: In a colorectal tumor model, myeloid- and NK-cell reprogramming with CAR mRNA/LNPs drove tumor regression, prolonged survival, remodeling of the tumor microenvironment, greater antigen presentation, and enhanced T-cell infiltration and activation. Likewise, T cell engineered with CAR mRNA/tLNPs elicited robust anti-tumor activity. Notably, co-delivery of cell-specific CAR mRNA/LNPs to both myeloid and T-cell compartments produced even stronger tumor control, highlighting the power of coordinated multi-lineage immune engineering.\nConclusions: This work demonstrates that simultaneous In vivo engineering of myeloid cells, T cells, and NK cells with CARs can orchestrate the coordinated actions of both innate and adaptive immunity for potent anti-tumor activity. This strategy offers a scalable and off-the-shelf approach for cell therapy and establishes a new therapeutic paradigm for overcoming the complexity of solid tumors.", "source_company": "Peter MacCallum Cancer Centre", "source_org_type": "医院", "row_number": 430, "target_meta": "HER2", "MOA_meta": "其他"}, {"drug_name": "CYT X300", "company": "Cytospire Therapeutics Ltd.", "org_type": "公司", "target": "EGFR x pan-gamma delta T cell", "modality": "bispecific antibody", "importance_level": "中", "total_score": 58.5, "institution_score": 65, "track_score": 85, "milestone_score": 30, "field_heat_score": 75, "bonus_score": 0, "brief_reason": "CYT X300为新型EGFR×pan-γδ T cell engager双抗，靶向EGFR并激活γδ T细胞用于实体瘤治疗。机构为早期biotech公司（非头部）、赛道热门（γδ TCE为下一代engager方向）但摘要禁运导致开发阶段和数据未披露，整体潜力中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11550", "id": "rVXM_5wBX1NQZOEH-LG6", "source_drug_name": "CYT X300", "title": "CYT X300, a novel EGFR x pan-gamma delta T cell engager for the treatment of solid tumors", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Cytospire Therapeutics Ltd.", "source_org_type": "公司", "row_number": 436, "target_meta": "EGFR", "MOA_meta": "双特异性抗体"}, {"drug_name": "anti-CEACAM6/EGFR bispecific antibody", "company": "Taipei Medical University", "org_type": "大学", "target": "CEACAM6/EGFR", "modality": "bispecific antibody", "importance_level": "中", "total_score": 58.5, "institution_score": 35, "track_score": 85, "milestone_score": 60, "field_heat_score": 75, "bonus_score": 3, "brief_reason": "双特异性抗体同时靶向CEACAM6和EGFR，通过诱导EGFR内吞和溶酶体降解克服抗EGFR耐药，机制新颖且针对EGFR驱动肿瘤有潜力。大学机构基础研究性质、仅异种移植模型阶段限制分数，但双抗+EGFR相关热门赛道和克服耐药亮点提供加分。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9659", "id": "rlXM_5wBX1NQZOEH-LG6", "source_drug_name": "anti-CEACAM6/EGFR bispecific antibody", "title": "Dual targeting of CEACAM6 and EGFR with a bispecific antibody induces EGFR degradation and overcomes anti-EGFR resistance", "abstract_text": "Epidermal growth factor receptor (EGFR) protein stability is an important determinant of tumor progression and therapeutic response. Here, we identified carcinoembryonic antigen-related cell adhesion molecule 6 (CEACAM6) as a previously unrecognized post-translational stabilizer of EGFR. CEACAM6 expression positively correlated with EGFR protein, but not mRNA, in clinical specimens. Mechanistically, CEACAM6 sequesters EGFR into CEACAM6-enriched lipid rafts, which delays the raft-associated endocytosis and lysosomal degradation of EGFR. This retention maintains EGFR clustering and sustains downstream ERK, AKT, and SRC signaling, promoting migration, invasion, and anoikis resistance, ultimately contributing to resistance against anti-EGFR therapeutics.\nTo therapeutically exploit this vulnerability, we developed an anti-CEACAM6/EGFR bispecific antibody (BsAb) that simultaneously engages both antigens on the tumor cell surface. The BsAb induces potent antigen crosslinking that triggers efficient EGFR internalization and redirects it toward lysosomal degradation, thereby bypassing the CEACAM6-dependent blockade of EGFR turnover. In addition, the BsAb efficiently suppressed the progression and metastasis of colorectal and lung cancer in xenograft models. These findings identify CEACAM6 as a critical regulator of EGFR stability and demonstrate that dual targeting with the bispecific antibody can induce EGFR degradation, thereby overcoming EGFR-driven malignancy.", "source_company": "Taipei Medical University", "source_org_type": "大学", "row_number": 437, "target_meta": "CEACAM6,EGFR", "MOA_meta": "双特异性抗体"}, {"drug_name": "Compound K", "company": "University of California San Francisco", "org_type": "大学", "target": "p53-R273H", "modality": "inhibitor", "importance_level": "中", "total_score": 58.5, "institution_score": 35, "track_score": 85, "milestone_score": 60, "field_heat_score": 80, "bonus_score": 8, "brief_reason": "Compound K为小分子化合物，通过恢复突变p53-R273H的DNA结合能力及肿瘤抑制功能，针对最常见p53突变之一，具有pH选择性机制和新颖修复策略。机构为大学导致institution_score较低，但mutant p53赛道热度高且bonus亮点明显，总分处于中偏上水平。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8838", "id": "xVXM_5wBX1NQZOEH-LG6", "source_drug_name": "Compound K", "title": "Small molecule restoring mutant p53R273H DNA binding and activity", "abstract_text": "Although mutations in TP53 are the most frequent genetic alteration in human cancers, approaches that target mutant p53 to restore p53-wild type (WT) tumor suppressor functions have had limited success and there are currently no FDA-approved therapeutics targeting mutant p53. We report a membrane-permeant small molecule, Compound K, that selectively increases tumor suppressor functions of p53-R273H, one of the two most common p53 mutants in cancers. Key to understanding the loss of tumor suppressor functions of p53-R273H is deprotonation of His273 at the higher intracellular pH (pHi) of cancer cells, which attenuates binding to the negatively charged phosphate backbone of DNA. We identified Compound K in a computational screen of 3.5 million small molecules for targeting deprotonated His273 and imparting a positive charge to restore electrostatic binding to DNA, like positively charged WT p53-Arg273. We find that Compound K selectively increases DNA binding by p53-R273H at the higher pH of cancer cells with no effect on DNA binding by p53-R273H at the lower pH of untransformed cells, or by p53-WT, p53-R175H, and other pH-regulated transcription factors at lower and higher pH values. Compound K also restores p53-WT functions in human PANC-1 pancreatic cancer cells that are homozygous for p53-R273H, with limited effects in human HPDE untransformed pancreatic epithelial cells, including >4200 DEGs in PANC-1 and <200 DEGs in HPDE, as determined by RNA-seq. In PANC-1 cells Compound K increases expression of loss-of-function, anti-tumorigenic genes, including GADD45A, KLF6, and IFIT2, and decreases expression of gain-of-function pro-tumorigenic genes, including CDC20, PLK1, AURKA, and for TGF-β signaling, as determined by RNA-seq and immunoblotting cell lysates. Compound K also selectively decreases viability of PANC-1 cells with no effect on HPDE cells, and tumorigenicity, determined by 80% reduced colony formation in soft agar. Our findings are an important step toward the unmet need of developing therapeutics targeting mutant p53 to limit cancer progression. Additionally, beyond p53-R273H, Arg>His mutations are enriched in many cancers, most notably medulloblastoma, acute myeloid leukemia, and pancreatic and prostate cancers, which makes our approach of targeting an Arg>His substitution to restore a positive charge have broad cancer therapeutic promise.", "source_company": "University of California San Francisco", "source_org_type": "大学", "row_number": 450, "target_meta": "not available", "MOA_meta": "抑制剂"}, {"drug_name": "personalized neoantigen vaccine", "company": "Memorial Sloan Kettering Cancer Center", "org_type": "医院", "target": "neoantigen", "modality": "mRNA", "importance_level": "中", "total_score": 58.5, "institution_score": 60, "track_score": 85, "milestone_score": 30, "field_heat_score": 80, "bonus_score": 0, "brief_reason": "该药物为个性化neoantigen疫苗，主要通过mRNA形式靶向肿瘤特异性新抗原，针对胰腺癌具有创新免疫机制。机构为顶尖癌症医院但非药企导致机构分一般，赛道为热门个性化mRNA疫苗但摘要无任何具体开发阶段或数据披露导致里程碑分低，总分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/324", "id": "BFXM_5wBX1NQZOEH-LK6", "source_drug_name": "personalized neoantigen vaccine", "title": "Personalized neoantigen vaccines for pancreatic cancer", "abstract_text": "There is no abstract associated with this presentation.", "source_company": "Memorial Sloan Kettering Cancer Center", "source_org_type": "医院", "row_number": 493, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "DVD-3E", "company": "tsinghua University", "org_type": "大学", "target": "未披露", "modality": "TCE", "importance_level": "中", "total_score": 58.5, "institution_score": 35, "track_score": 85, "milestone_score": 60, "field_heat_score": 75, "bonus_score": 6, "brief_reason": "DVD-3E为logic-gated TCE融合mutant IL-2，在肿瘤微环境局部激活实现更安全有效的实体瘤免疫治疗，未明确具体靶点。清华大学基础创新设计亮点突出，TCE+局部细胞因子热门赛道加分，但学术机构+preclinical阶段限制总体评分。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10800", "id": "S1XM_5wBX1NQZOEH-LK6", "source_drug_name": "DVD-3E", "title": "Logic-gated T cell engager linked with mutant IL-2 for safer and better effective solid tumor immunotherapy", "abstract_text": "T cell engagers (TCEs) have achieved transformative success in B-cell malignancies but show limited efficacy in solid tumors with severe toxicity. Here, we identify insufficient IL-2 signaling as a key bottleneck for sustaining TCE-induced T-cell function. Although exogenous IL-2 enhances TCE efficacy, its systemic administration causes more severe toxicity. To overcome this limitation, we engineered a protease-activatable dual-variable-domain (DVD) as Pro-TCE to reduce its off-tumor toxicity. Furthermore, we designed a mutant IL-2 (3E) with markedly reduced receptor affinity that is inactive in periphery. The construct (DVD-3E) remains inert in circulation and becomes locally activated only upon tumor-specific protease cleavage, coupling T-cell engagement with cis IL-2 signaling. This logic-gated design restricts both TCE and cytokine activity to the tumor microenvironment (TME), enabling potent antitumor responses without systemic toxicity. Mechanistically, DVD-3E enhances the persistence and effector function of preexisting intratumoral T cells, expands TCF1⁺ progenitor and antigen-specific T cells populations, mitigates exhaustion, and establishes durable immune memory. Notably, DVD-3E treatment increased the frequency of antigen-specific T cells in draining lymph nodes, which were capable of controlling distant tumors and mediating effective tumor regression upon adoptive transfer. These findings define a new design principle for logic gated TCEs that achieve a favorable balance between safety and efficacy, offering a strategy to overcome current therapeutic resistant.", "source_company": "tsinghua University", "source_org_type": "大学", "row_number": 535, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "A8E-N108Q-R26G", "company": "Tianjin Medical Univ. Cancer Inst. & Hospital", "org_type": "医院", "target": "未披露", "modality": "other", "importance_level": "中", "total_score": 58.5, "institution_score": 35, "track_score": 85, "milestone_score": 70, "field_heat_score": 75, "bonus_score": 5, "brief_reason": "A8E-N108Q-R26G为高保真腺嘌呤碱基编辑器，用于体内精准矫正STK11Q37*突变以增敏放疗，靶点未作为药物直接靶向而是基因编辑对象。机构为国内医院得分较低，但基因编辑+放疗增敏在NSCLC领域机制新颖且具协同抗瘤潜力，赛道热度和POC数据支撑中等重要性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10435", "id": "a1XM_5wBX1NQZOEH-LK6", "source_drug_name": "A8E-N108Q-R26G", "title": "In vivo adenine base editing of STK11Q37* reprograms tumor for radiosensitizing effect", "abstract_text": "In this study, we aim to investigate the therapeutic potential of in vivo genetic therapy using AAV-mediated adenine base editor (ABE) delivery for non-small cell lung cancer (NSCLC) carrying the STK11 nonsense mutation STK11Q37* (c.109C>T), and further explore the molecular mechanisms underlying its impact on radiosensitivity. Radiotherapy is a standard treatment for locally advanced or inoperable NSCLC patients, radiation resistance driven by tumor-promoting somatic mutations severely limits clinical efficacy, underscoring the urgent need for targeted strategies such as precise gene correction to overcome this barrier. Through CRISPR-based in vivo mutation library screening combined with whole-exome sequencing, we identified STK11Q37* as a critical driver of radiation resistance. To restore STK11 function, we engineered a panel of ABEs with distinct PAM/TAM compatibilities and further developed a high-fidelity variant, A8E-N108Q-R26G, which enables precise correction of the pathogenic adenine without bystander editing. Using HEK293T reporter cells stably harboring the STK11Q37* locus, we found that spCas9-A8EQR (N108Q-R26G) achieved the highest overall correction efficiency, repairing up to 60% of mutant alleles with superior fidelity. The optimized editor was subsequently packaged into a dual-AAV system and delivered in vivo to humanized mice bearing subcutaneous patient-derived organoid xenografts. AAV-mediated base editing combined with radiotherapy produced synergistic antitumor effects and significantly suppressed tumor progression. Mechanistic studies revealed that precise correction of STK11Q37* restores endogenous LKB1 protein expression and kinase activity, reactivating downstream signaling required for maintaining redox homeostasis. Restored LKB1 directly stabilizes the transcriptional regulator BACH1 by limiting its ubiquitination and proteasomal degradation, thereby preserving BACH1-mediated repression of antioxidant gene programs. Concurrently, LKB1 re-expression dampens NRF2 nuclear accumulation and transcriptional activity, leading to reduced expression of NRF2-driven detoxification and antioxidant pathways. This coordinated regulation markedly elevates intracellular ROS levels following irradiation and reinstates radiation-induced cytotoxic stress, collectively enhancing tumor radiosensitivity. In summary, our study identifies STK11Q37* as a therapeutically actionable driver of radiation resistance and demonstrates that precise ABE-mediated correction provides a promising gene-editing-based strategy to improve treatment outcomes in NSCLC.", "source_company": "Tianjin Medical Univ. Cancer Inst. & Hospital", "source_org_type": "医院", "row_number": 555, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "PI3K/RAS breakers", "company": "ICE Bioscience", "org_type": "公司", "target": "未披露", "modality": "other", "importance_level": "中", "total_score": 58.5, "institution_score": 40, "track_score": 85, "milestone_score": 50, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "PI3K/RAS breakers为针对KRAS抑制剂耐药的潜在新型组合策略药物，靶点机制未明确披露，属于RAS/PI3K通路热门赛道。ICE Bioscience作为国内CRO服务机构而非创新药企，preclinical筛选平台有一定价值但开发阶段早期且无明确里程碑亮点。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5065", "id": "fFXM_5wBX1NQZOEH-LK6", "source_drug_name": "PI3K/RAS breakers", "title": "Resistant cell panel-based discovery of multi-target combinations and mechanisms to overcome KRAS inhibitor resistance", "abstract_text": "Background: KRAS mutations are common oncogenic drivers in solid tumors, and KRAS-targeted inhibitors have revolutionized treatment. However, inherent and acquired resistance limits long-term clinical benefit, highlighting the need for effective combination strategies and their mechanisms.\nMethods: 1) Generation of KRAS inhibitor-resistant cell lines: Over 10 resistant cell lines were established by long-term exposure of KRAS-mutant cancer cells to clinically approved KRAS inhibitors and novel agents (e.g., KRAS molecular glues, PI3K/RAS breakers). 2) Resistance mechanism exploration: Multi-omics bioinformatics analyses (transcriptomics, proteomics) were performed to dissect molecular drivers of resistance and predict potential synergistic combination partners. 3) High-throughput combination screening: More than 100 drug combinations (including KRAS inhibitors, targeted agents against bypass pathways, and novel scaffolds) were tested using a customized resistant cell panel to identify regimens that overcome resistance. 4) Mechanistic validation: Key signaling pathways (e.g., MAPK, PI3K-AKT, STAT3) were interrogated via Western blot, and phospho-protein arrays to confirm the functional relevance of predicted resistance mechanisms and combination efficacy.\nResults: Bioinformatics analyses of resistant cell lines revealed diverse resistance mechanisms, including upregulation of bypass signaling cascades, KRAS isoform switching, and adaptive metabolic rewiring. High-throughput screening identified several promising drug combinations that restored sensitivity to KRAS inhibitors in resistant cells, with combinations of KRAS inhibitors plus PI3K/RAS breakers or pathway-specific inhibitors showing the most potent synergistic effects. Mechanistic validation confirmed that these combinations effectively abrogated aberrantly activated resistance-related signaling pathways, reversing the resistant phenotype. Additionally, the customized cell panel enabled rapid ranking of KRAS inhibitor monotherapy and combination efficacy across distinct KRAS mutation subtypes.\nConclusions: Our study establishes a robust platform of KRAS inhibitor-resistant cell lines and a high-throughput screening system for identifying resistance-overcoming combinations. The identified synergistic regimens and their validated mechanisms provide critical preclinical evidence to guide the development of next-generation KRAS-targeted combination therapies, addressing the unmet clinical need of overcoming resistance in KRAS-mutant cancers.", "source_company": "ICE Bioscience", "source_org_type": "公司", "row_number": 565, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "IL-18-armored DLL3-directed CAR T cells", "company": "Memorial Sloan Kettering Cancer Center", "org_type": "医院", "target": "DLL3", "modality": "CAR", "importance_level": "中", "total_score": 58.5, "institution_score": 40, "track_score": 85, "milestone_score": 50, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "靶点为DLL3，采用IL-18加持的CAR-T模式，机制新颖增强实体瘤抗肿瘤活性。机构为顶级癌症中心但非药企导致institution_score较低，热门赛道CAR+IL-18 armor及DLL3在神经内分泌瘤潜力支撑中高分，但仍处preclinical体外阶段无明确临床里程碑。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1770", "id": "Tp7ECZ0BZznHJdntvNYd", "source_drug_name": "IL-18-armored DLL3-directed CAR T cells", "title": "Preclinical efficacy of DLL3 targeted CAR T cells in neuroblastoma", "abstract_text": "Background: Neuroblastoma (NBL), the most common extracranial solid tumor in children, accounts for 15% of pediatric cancer deaths, and survival after relapse remains <50%. To expand immunotherapeutic options, we evaluated Delta-like ligand 3 (DLL3), an inhibitory NOTCH ligand normally silenced in healthy tissues but aberrantly expressed in neuroendocrine tumors. NOTCH dysregulation in NBL and emerging datasets indicating DLL3 expression support investigation of DLL3 as a target and assessment of IL-18-armored DLL3-directed CAR T cells originally developed for small-cell lung cancer.\nMethods: DLL3 expression was assessed in NBL patient samples and PDX models by RNA sequencing, immunohistochemistry (IHC), and flow cytometry. IL-18-armored DLL3 CAR T cells were tested in vitro against NBL cell lines across multiple effector-to-tumor (E:T) ratios. Cumulative killing was compared using Vardi’s test for area-under-the-curve analysis, and Wilcoxon rank-sum tests evaluated differences at individual E:T ratios.\nResults: RNA sequencing of pediatric solid tumors treated at MSK (n=540) showed that NBL (n=109) had the highest DLL3 transcript levels relative to other non-CNS tumors (0-19.7 TPM; median 0.38). In NBL patient samples, IHC (n=31) demonstrated DLL3 protein expression (H-score ≥10, range 10-300, median 100) in 52% (16/31) with strong transcript-protein concordance (Spearman r=0.847, p=2×10-9). In NBL PDX models, DLL3 protein expression was detected in 63% (19/30), with H-scores ranging 10-123 (median 73). Flow cytometry across five PDX models spanning H-scores 7-105 showed DLL3 surface expression on 25-88% of tumor cells, confirming antigen accessibility. IL-18-armored DLL3-CAR T cells exhibited significantly greater cumulative cytotoxicity than untransduced T cells against two DLL3+ NBL cell lines, SK-N-DZ (51% DLL3+, p=0.03) and SK-N-SH (29% DLL3+, p=0.03), with activity across multiple E:T ratios (p<0.05). To confirm antigen specificity, IL-18-armored DLL3-CAR T cells were compared with a clinical-grade IL-18-armored CD371-directed CAR (CLEAR AML) as a non-DLL3-targeting control. DLL3-CAR T cells exhibited significantly greater cytotoxicity against both cell lines (SK-N-DZ, p=0.0006; SK-N-SH, p=0.0004) and outperformed the control CAR across all E:T ratios (p<0.001).\nConclusions: DLL3 is expressed in a subset of NBL patient tumors and PDX models and is accessible for CAR targeting. IL-18-armored DLL3-directed CAR T cells show strong in vitro cytotoxicity against DLL3+ NBL models. In vivo testing in a DLL3+ NBL PDX is underway. These findings support DLL3 as a promising immunotherapeutic target and justify further development of DLL3-directed CAR T therapy for NBL.", "source_company": "Memorial Sloan Kettering Cancer Center", "source_org_type": "医院", "row_number": 579, "target_meta": "DLL3", "MOA_meta": "其他"}, {"drug_name": "anti-LIF neutralizing antibody", "company": "NYU Grossman School of Medicine", "org_type": "大学", "target": "LIF", "modality": "neutralizing antibody", "importance_level": "中", "total_score": 58.5, "institution_score": 40, "track_score": 70, "milestone_score": 75, "field_heat_score": 70, "bonus_score": 5, "brief_reason": "靶点为LIF，通过中和抗体阻断LKB1突变肺腺癌中的自泌信号，消除炎症性癌干细胞并逆转免疫抑制微环境。大学机构基础研究，动物模型中显示显著疗效和T细胞依赖性抗瘤作用，但尚未进入临床开发，赛道有一定热度但非顶级热门。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/2044", "id": "k1XM_5wBX1NQZOEH-LK6", "source_drug_name": "anti-LIF neutralizing antibody", "title": "Autocrine LIF signaling: A novel therapeutic target to eliminate inflammatory and immunosuppressive cancer stem cells in LKB1 mutant lung adenocarcinoma", "abstract_text": "As tumors proliferate from a single cell of origin, they develop adaptations to circumvent stressors faced in the tumor microenvironment (TME). These adaptations include acquisition of mutations that enable tumors to suppress immune surveillance. Liver Kinase B1 (LKB1), encoded by the gene STK11, is mutated in approximately 20% of lung adenocarcinoma (LUAD) cases. While immune checkpoint blockade (ICB) is the standard of care therapy for advanced LUAD, LKB1 mutant LUAD is associated with poor response rates to ICB. The mechanism in which LKB1 regulates the TME and ICB responses remains unknown and understanding this mechanism can lead to the development of novel immune based therapies that can target LKB1 mutant LUAD.\nTo investigate how LKB1 mutations in cancer cells alter the surrounding TME we utilized a genetically engineered mouse model (GEMM) combined with in vivo CRISPR/Cas9 editing where a lentivirus expressing a sgRNA targeting Lkb1 (sgLkb1) or non-targeting control (sgNeo) and Cre recombinase, are intratracheally administered to KrasLSL-G12D/+ Tp53fl/fl Rosa26LSL-Cas9-P2A-GFP/LSL-Cas9-P2A-GFP mice to initiate autochthonous KrasG12D/+ Tp53-/- (KP) lung tumors with and without deletion of Lkb1. Eleven weeks after tumor initiation, immune cells were isolated from the lungs and immune profiling using flow cytometry and scRNA-seq was performed. Flow cytometry analysis of tumor bearing lungs revealed that both CD4 and CD8 T cell function was heavily impaired specifically in the setting of Lkb1 mutant tumors as demonstrated by decreased expression of IFNγ and TNFα. Further analysis of immune populations through scRNA-seq identified two subsets of myeloid cells enriched in Lkb1 mutant tumors: SiglecFHi neutrophils and Arg1+ interstitial macrophages, each expressing immunosuppressive gene signatures.\nTo delineate the mechanism in which Lkb1 mutant lung tumors remodel the TME with immunosuppressive myeloid cells, we performed RNA-seq on Lkb1 mutant and wildtype tumors sorted from our GEMM. This revealed that Lkb1 mutant tumors upregulate a range of cytokines involved in myeloid cell recruitment and polarization including Il6, Ccl2, and Csf3. One notable gene upregulated in Lkb1 mutants was the cytokine Leukemia inhibitory factor (Lif). Elevation of these cytokines, including LIF, was verified at the protein level through multiplex cytokine analysis of bronchoalveolar lavage (BAL) fluid. Furthermore, analysis of TCGA dataset confirmed that LKB1 mutant LUAD have increased expression of LIF. Using KP LUAD cell lines we mapped out that LKB1 transcriptionally regulates Lif through the SIK/CRTC2 pathway. Since LIF signals through its receptor (LIFR) primarily through STAT3, we measured the expression of pSTAT3, the active form of STAT3. Remarkably, there was increased intra-tumoral pSTAT3 in murine and human tumor samples with LKB1 mutations.\nBecause of the increased intra-tumoral pSTAT3 expression, we hypothesized that Lkb1 mutant tumor derived LIF was signaling on tumors in an autocrine loop. To investigate the presence of autocrine LIF signaling, we utilized a paired guide approach to generate Lkb1 mutant tumors with and without deletion of either Lif (sgLif) or Lifr (sgLifr). Both deletion of Lif and Lifr in tumor cells led to a decrease in intra-tumoral pSTAT3 and reduction in tumor burden compared to Lkb1 mutant tumor controls verifying that autocrine LIF signaling was active and driving tumorigenesis. Reflective of decreased inflammation, we found that BAL fluid levels of IL6, CSF3, and CCL2 were lower with disruption of LIF signaling. To examine the immune infiltrate in this model, we employed the platform Expanded Cellular Indexing of Transcriptomes and Epitopes by sequencing (ExCITE-seq) which enables analysis of gene expression, surface protein expression, and TCR sequencing at a single cell resolution. This analysis revealed that disruption of autocrine LIF signaling in tumors led to decreased infiltration by SiglecFHi neutrophils and Arg1+ interstitial macrophages. We leveraged our ExCITE-seq data set and assessed T cell clonality in each of the tumor genetic conditions and found an expansion of T cell clones specifically in the context of Lif or Lifr deletion. Corresponding with this increased clonality, we detected an increase in T cell expression of IFNγ and TNFα with disruption of LIF signaling. Overall, genetic deletion of LIF signaling in Lkb1 mutant tumors reversed the immunosuppressive myeloid infiltrate and augmented T cell function.\nTo understand the signaling process downstream of LIFR, we extended our ExCITE-seq analysis to tumor cells. Subclustering tumor cells identified unique cancer cell states labeled 1 - 8 exhibiting the significant heterogeneity within Lkb1 mutant tumors. Pathway analysis revealed that cancer cell states 5 and 8 have high expression of an Inflammatory Response pathway and genes associated with stemness. Furthermore, states 5 and 8 lacked expression of Nkx2-1 reflecting a dedifferentiated state compared to state 1 which had high expression of Nkx2-1 and a gene signature associated with alveolar type 2 (AT2) cells. Notably, deletion of Lif and Lifr resulted in the selective elimination of these inflammatory cancer stem cell states. Differential gene analysis identified that cell state 5 highly expressed the gene Sox17. Given that the transcription factor Sox17 was specifically expressed in the inflammatory cancer stem cells, we questioned whether Sox17 was driving the inflammatory and immunosuppressive nature of Lkb1 mutant tumors. Deletion of Sox17 in Lkb1 mutant tumors resulted in a significant decrease in tumor burden. Furthermore, loss of Sox17 also led to a reduction in cytokines such as IL6, CSF3, and CCL2 as well as an increase in CD4 and CD8 T cell function.\nFrom a clinical perspective, LKB1 mutant LUAD reflects an aggressive and treatment resistant subtype of lung cancer. To evaluate the therapeutic potential of targeting LIF in Lkb1 mutant tumors, we initiated Lkb1 mutant lung tumors using our KP LUAD GEMM. Eight weeks after tumor initiation we treated tumor bearing mice with an anti-LIF neutralizing antibody for three weeks. Tumor burden was significantly reduced with anti-LIF therapy demonstrating that targeting LIF is effective in impairing tumorigenesis in established tumors. ExCITE-seq analysis confirmed that anti-LIF therapy selectively eliminated the Sox17+ cancer cell state supporting the notion that the LIF is needed for the maintenance of this subpopulation. With the loss of the inflammatory cancer stem cells, the immunosuppressive TME was reversed with anti-LIF therapy as demonstrated by a decrease in SiglecFHi neutrophils and Arg1+ interstitial macrophages along with a reduction of cytokines such as IL6, CSF3, and CCL2. To establish the importance of T cells on the effect of LIF neutralization, we treated mice bearing Lkb1 mutant lung tumors with a combination of anti-LIF antibody, anti-CD4/anti-CD8 antibodies, or the combination of these antibodies. Anti-LIF therapy was ineffective in the absence of T cells, demonstrating that the inhibitory effect of LIF neutralization on tumor growth is T cell mediated.\nIn summary, we established through a comprehensive mechanistic analysis of the TME of lung tumors derived from a KP GEMM, that Lkb1 mutant lung tumors transcriptionally upregulate the cytokine Lif. These tumors harness autocrine LIF signaling to induce tumor plasticity and nurture an inflammatory cancer stem cell subpopulation driven by Sox17. These cancer stem cells produce cytokines that remodel the TME with immunosuppressive SiglecFHi neutrophils and Arg1+ interstitial macrophages that dampen anti-tumor T cell function. Targeting LIF signaling is a novel therapeutic approach to reverse the immunosuppressive nature of LKB1 mutant lung tumors, enhance anti-tumor immune response, and ultimately impair tumor growth.", "source_company": "NYU Grossman School of Medicine", "source_org_type": "大学", "row_number": 582, "target_meta": "LIF", "MOA_meta": "抗体"}, {"drug_name": "CDK-TCIP", "company": "ICE Bioscience", "org_type": "公司", "target": "CDK2/CDK9", "modality": "other", "importance_level": "中", "total_score": 58.5, "institution_score": 45, "track_score": 85, "milestone_score": 50, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "CDK-TCIP为新型转录化学诱导邻近物（TCIP），通过招募CDK9实现转录重编程，而CDK2分子胶诱导降解，靶向CDK2/9；ICE Bioscience为国内CRO服务公司，非头部药企，preclinical平台研究展示机制链接但无临床进展，热门分子胶/TCIP赛道加分，总分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8728", "id": "XVXM_5wBX1NQZOEH-LO6", "source_drug_name": "CDK-TCIP", "title": "When CDK meets CIP: Linking target engagement to functional outcomes in CDK2 molecular glue and CDK‑TCIP", "abstract_text": "Background: Cyclin‑dependent kinases (CDKs) orchestrate cell cycle progression and transcriptional control, and their dysregulation is a hallmark of cancer. While conventional CDK inhibitors have shown utility, emerging modalities such as molecular glues (MGs) and transcriptional/epigenetic chemical inducers of proximity (TCIPs) offer novel mechanisms to modulate or utilize CDK activity. CDK2 MG promote selective degradation of CDK2 complexes, whereas CDK9 TCIP induce proximity‑driven transcriptional rewiring. The purpose of this study was to demonstrate linkage of target engagement to cellular outcomes across these two modalities, thereby establishing mechanistic insights for next‑generation CDK therapeutics.\nMethods: We developed an integrated platform combining biophysical binder screening (Spectrum Shift, SPR, HTRF), cellular assays of CDK2 degradation and cell cycle control (proliferation, phospho‑RB, flow cytometry), mechanism‑of‑action studies in CCNE‑amplified and resistant models with drug combinations, CDK‑TCIP engagement and transcriptional assays (NanoBRET, BCL6 reporter, qPCR), downstream functional profiling (viability, apoptosis, cancer cell panels, primary cell lines), and off‑target evaluation by Western blotting, proteomics, and ICESTP safety panels.\nResults: CDK2 MG induced robust CDK2/CRBN ternary complex formation and degradation of CDK2, leading to reduced proliferation, decreased phospho‑RB, and G1 arrest. CCNE amplification conferred heightened sensitivity, while palbociclib resistant cell lines revealed CDK2 MG as a potential strategy to overcome drug resistance. In contrast, CDK‑TCIP stabilized ternary complexes that drove nuclear translocation and transcriptional activation, evidenced by BCL6 reporter activation and target qPCR upregulation. Functional assays demonstrate broad vulnerability across cancer cell panels, with apoptosis induction in select primary cell lines. Off‑target profiling confirmed high selectivity, with minimal liabilities detected across proteomic and ICESTP safety screens.\nConclusions: This study provides comprehensive profiling showing that CDK2 MGs and CDK‑TCIPs achieve distinct biological outcomes through degradation versus transcriptional rewiring. By integrating biophysical, biochemical, and cellular analyses, we establish quantitative links between target engagement and phenotypic consequences. These findings define mechanistic frameworks for optimizing CDK‑targeting modalities and inform rational design of selective, context‑dependent interventions in oncology.", "source_company": "ICE Bioscience", "source_org_type": "公司", "row_number": 713, "target_meta": "CDK2,CDK9", "MOA_meta": "其他"}, {"drug_name": "merodantoin", "company": "National University of Singapore", "org_type": "大学", "target": "KRAS", "modality": "inhibitor", "importance_level": "中", "total_score": 58.5, "institution_score": 35, "track_score": 85, "milestone_score": 70, "field_heat_score": 80, "bonus_score": 5, "brief_reason": "merodantoin为小分子，通过诱导突变KRAS激活依赖的ROS增加触发铁死亡，选择性杀伤KRAS突变PDAC细胞。机构为大学得较低分，但KRAS相关铁死亡新策略赛道热门、展示PDX器官样及原位模型疗效具一定里程碑价值，故综合为中重要性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1849", "id": "vFXM_5wBX1NQZOEH-LO6", "source_drug_name": "merodantoin", "title": "Small molecule induced KRAS activation triggers ferroptosis in mutant KRAS expressing PDAC", "abstract_text": "Pancreatic ductal adenocarcinoma (PDAC) is the most prevalent histological subtype of pancreatic cancer with limited treatment options and poor prognosis. More than 90% of PDAC harbor mutations in the oncogene KRAS and are dependent on downstream pro-survival and/or proliferative factors such as AKT, MEK and MAPK. As such, targeting these downstream pathways has been employed as a therapeutic strategy, however, recent success in developing KRAS-specific inhibitors has added an important dimension in the management of PDAC. The clinical efficacy of the direct KRAS inhibitors has been less than optimal, which circumvents the need for identifying new therapeutic strategies. To that end, we recently described a novel approach using a small molecule that induced KRAS activation-dependent, ROS-mediated, execution of mutant KRAS driven cancer cells (Iskandar, K. et al. Autophagy 2024). Here we investigated the effect of this small molecule (merodantoin; C1) on mutant KRAS expressing PDAC. Results show that C1 selectively targets PDAC cells (cytotoxicity, colony formation and spheroid formation) harboring G12 KRAS mutation compared to wild-type KRAS expressing cells. Mechanistically, C1 treatment led to significant increase in both intracellular and mitochondrial reactive oxygen species (ROS), increase in labile iron levels due to increased transferrin receptor 1 (TfR1) and decreased ferritin heavy chain (FTH1), and disruption of the glutathione-based antioxidant system by reducing cystine uptake and decreasing Glutathione peroxidase 4 (GPX4) expression. These changes together triggered lipid peroxidation, a key sign of ferroptosis. Experiments using ferroptosis inhibitors, iron chelators, and ROS scavengers restored cell viability, confirming that C1 triggered cell death in PDAC cells by ferroptosis. Importantly, genetic and pharmacological modulation of KRAS provide evidence that mutant KRAS is upstream of ferroptotic cascade. Moreover, KRAS mutations were shown to make PDAC cells more sensitive to ferroptosis by naturally lowering their antioxidant defences and iron storage capacity. This was evident in the reduced baseline expression of GPX4 and SLC7A11, along with decreased cystine uptake in mutant KRAS expressing cell lines compared to wild-type controls. Beyond in vitro validation, C1 demonstrated strong effectiveness in patient-derived PDAC organoids and significantly limited tumor growth in a orthotopic PDAC mouse model. Evidence presented here strongly argue in support of targeting ferroptosis vulnerability of KRAS-mutant PDAC as a novel treatment strategy.", "source_company": "National University of Singapore", "source_org_type": "大学", "row_number": 780, "target_meta": "KRAS", "MOA_meta": "抑制剂"}, {"drug_name": "PARP inhibitor", "company": "IMBDx", "org_type": "其他", "target": "未披露", "modality": "inhibitor", "importance_level": "中", "total_score": 58.5, "institution_score": 45, "track_score": 75, "milestone_score": 55, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "该记录聚焦PARP抑制剂在卵巢癌维持治疗中的HRD（尤其是WES-based HRD≥50）预测价值验证，靶点为PARP但未披露具体药物；IMBDx为韩国上市精准肿瘤诊断公司，非头部药企故机构分中等，HRD/PARPi赛道在卵巢癌领域仍具热度，摘要提供临床验证数据但非药物开发里程碑。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10954", "id": "xlXM_5wBX1NQZOEH-LO6", "source_drug_name": "PARP inhibitor", "title": "Clinical validation of WES-based HRD scoring and its prognostic value for PARP inhibitor maintenance therapy in ovarian cancer", "abstract_text": "Background: Homologous recombination deficiency (HRD) predicts PARP inhibitor (PARPi) sensitivity in ovarian cancer. We evaluated the clinical and analytical performance of a WES-based genomic profiling assay generating HRD scores and BRCA status, and assessed its prognostic value for PARPi maintenance.\nMethods: We included 81 consecutive patients with epithelial ovarian cancer (FIGO I-IV) who had received PARPi therapy between 2017-2024 at Seoul National University Hospital. After tumor purity estimation and microdissection, formalin-fixed, paraffin-embedded (FFPE) surgical tumor tissues and matched blood were analyzed using the CancerProfiler™ WES panel. HRD scores were derived from genomic scar metrics (LOH, TAI and LST) following the scarHRD algorithm. Germline and somatic BRCA1/2 variants were profiled concurrently. HRD-high status was defined at ≥42 and ≥50. Tumor purity and fraction were estimated from WES data and incorporated into HRD computation to ensure quantitative stability.\nResults: Median age was 56; 96% had high-grade serous carcinoma and 94.8% FIGO III-IV disease. Optimal cytoreduction (<1 cm residual) was achieved in 61%, and 52% received neoadjuvant chemotherapy. By the WES panel assay, a total of 46 patients had germline or somatic BRCA mutations. HRD-high status was observed in 77.8% at ≥42 and 66.7% at ≥50; the ≥50 cutoff showed a stronger association with germline BRCA (OR 3.15; p=0.021). Among 73 PARPi maintenance recipients (52 first-line and 23 second-line), HRD ≥50 showed differential predictive value by NAC. In first-line recipients, PFS was similar between HRD-high and -low after NAC (15.3 vs 11.3 mo, p=0.77) but markedly longer in HRD-high without NAC (median not reached vs 7.66 mo, p=0.001). This pattern persisted in the second-line setting (NAC: 19.48 vs 6.49 mo, p=0.049; no NAC: 17.78 vs 2.43 mo, p<0.001). BRCA mutation predicted benefit only in NAC-treated first-line patients (17.7 vs 4.5 mo, p=0.007) and not elsewhere. HRD-high was an independent predictor of longer PFS (first-line HR=0.26, p=0.02; second-line HR=0.20, p=0.029). In multivariable analyses, the predictive value of PARP inhibitors was BRCA-dependent only in the first-line setting (HR=0.09, p=0.001), with no significant association observed in the second-line (HR=0.28, p=0.226). By contrast, HRD-high status remained a consistent independent predictor in both first- (HR=0.26, p=0.02) and second-line therapy (HR=0.02, p=0.029), emerging as the sole significant determinant after recurrence.\nConclusions: HRD ≥50 is a robust predictor of PARPi benefit—particularly in treatment-naïve tumors—whereas BRCA status shows limited and NAC-dependent predictive value. These findings support prospective multi-center validation of WES-based HRD assays as scalable alternatives to array-based platforms.", "source_company": "IMBDx", "source_org_type": "其他", "row_number": 787, "target_meta": "not available", "MOA_meta": "抑制剂"}, {"drug_name": "a novel dual-payload ADC candidate", "company": "ICE Bioscience", "org_type": "公司", "target": "未披露", "modality": "ADC", "importance_level": "中", "total_score": 58.5, "institution_score": 45, "track_score": 90, "milestone_score": 40, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "药物为新型双payload ADC，靶点未披露，聚焦Top1抑制剂+CHK抑制剂组合以克服CRC异质性和耐药。ICE Bioscience作为国内CRO而非头部药企得较低机构分，双payload ADC为ADC领域热门创新方向得高赛道分，但仍处概念验证阶段无明确临床里程碑。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5431", "id": "yVXM_5wBX1NQZOEH-LO6", "source_drug_name": "a novel dual-payload ADC candidate", "title": "Enhancing dual-payload ADC discovery projects by overcoming heterogeneity and resistance through dual-payload innovation", "abstract_text": "Dual-payload antibody-drug conjugates (ADCs) have emerged as an innovative promising next-generation ADC format, delivering two cytotoxic agents to enhance efficacy through synergistic effects, mitigate resistance, without an accompanying increase in toxicity risk, aiming to address the challenge of poor-responsive cancers and rapid patient relapses. The success of dual-payload ADCs hinges on the appropriate dual-payload combination.DNA-damage response (DDR) inhibitors are increasingly being evaluated as payloads for ADCs, with Topoisomerase 1 (Top 1) inhibitors being the most commonly used class. Top 1 inhibition traps DNA breaks at replication forks, simultaneously blocking the DDR pathway severs the repair escape route, leading to replication catastrophe and selective synthetic-lethal cell death.To identify a rationally designed dual-payload combination that overcomes tumor heterogeneity and conventional resistance of colorectal cancer (CRC), synergistic pairs of Top 1 inhibitors and a group of DDR inhibitors with different mechanisms were screened and evaluated. Single payload activities were first investigated in CRC cell panel, and dual-payload combination synergies were then assessed in some selected CRC cell lines and ADC-related drug-resistant cell lines. A pair of Top 1 inhibitor + CHK inhibitor combination showed significant potent synergy in CRC cell lines and ADC-related drug-resistant cell lines with 2D and 3D cytotoxicity evaluation models. Mechanistic studies of this combination were further explored with cell cycle and apoptosis studies, WB of biomarkers, as well as RNA-Sequencing, revealing that the synergy stemmed from coordinated cell cycle arrest and enhanced apoptosis induction, supported by transcriptomic profiling of DDR pathways. Critically, the dual-payload combination showed no increased toxicity in a group of healthy human cell lines and limited or additive hematotoxicity in the in vitro CD34+ HSPCs myeloid progenitor cell proliferation and differentiation assays, indicating a potentially improved therapeutic window. These study strategies and findings accelerate dual-payload ADC innovative research, especially in the stage of proof of concept for dual-payload combination as a promising strategy to overcome cancer heterogeneity and resistance", "source_company": "ICE Bioscience", "source_org_type": "公司", "row_number": 791, "target_meta": "not available", "MOA_meta": "抗体偶联药物"}, {"drug_name": "a potent allosteric WIP1 inhibitor", "company": "Reaction Biology Europe GmbH", "org_type": "公司", "target": "WIP1 (PPM1D)", "modality": "inhibitor", "importance_level": "中", "total_score": 58.5, "institution_score": 45, "track_score": 65, "milestone_score": 70, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "靶向WIP1/PPM1D的别构抑制剂，WIP1作为DNA损伤响应负调控因子在多种癌症中过表达，具有潜在抗肿瘤价值。机构为CRO服务公司，非主要研发实体，得分中等；赛道为磷酸酶抑制剂，preclinical数据较完整包括体内疗效，但领域整体热度不高且无临床进展。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4404", "id": "aVXM_5wBX1NQZOEH-LS6", "source_drug_name": "a potent allosteric WIP1 inhibitor", "title": "Establishment of assay systems for drug development against the oncogenic phosphatase WIP1", "abstract_text": "The serine/threonine phosphatase WIP1 (PPM1D) is a key negative regulator of the DNA damage response (DDR) and a recognized oncogene, frequently amplified or truncated in various cancers including breast, ovarian, neuroblastoma, and glioblastoma. Its inhibition restores DDR signaling, offering a promising therapeutic strategy. Despite initial efforts, including the development of the allosteric inhibitor GSK2830371, clinical translation has been limited. We report the establishment of a comprehensive assay platform to support drug development targeting WIP1. Biochemical assays were optimized using fluorescein diphosphate (FDP), malachite green with phosphopeptides (p53, H2AX, p38 MAPK), and TR-FRET formats, enabling robust activity profiling. Cellular mechanism-of-action assays were developed to monitor phosphorylation changes in WIP1 substrates, with pS15-p53 ELISA in U2OS cells selected for medium-throughput iterative compound profiling. Phenotypic assays demonstrated compound efficacy in 2D and 3D proliferation models, with leukemic cell lines showing pronounced sensitivity. Combination studies revealed strong synergy between WIP1 inhibitors and MDM2 antagonists (e.g., Nutlin3a), supporting a dual-targeting approach for p53 pathway reactivation. In vivo efficacy was confirmed in MV4-11 xenograft models, with dose-dependent tumor growth inhibition and favorable tolerability profiles. Our integrated assay suite enables iterative screening and lead optimization, culminating in the identification of a potent allosteric WIP1 inhibitor with nanomolar activity and promising preclinical efficacy. These findings support WIP1 as a viable target in oncology and provide a foundation for future clinical development.", "source_company": "Reaction Biology Europe GmbH", "source_org_type": "公司", "row_number": 904, "target_meta": "PPM1D", "MOA_meta": "抑制剂"}, {"drug_name": "antisense oligonucleotides", "company": "INSERM", "org_type": "研究机构", "target": "Furin and PCSK7", "modality": "ASO", "importance_level": "中", "total_score": 58.5, "institution_score": 35, "track_score": 85, "milestone_score": 60, "field_heat_score": 75, "bonus_score": 3, "brief_reason": "ASO靶向Furin和PCSK7调控免疫检查点表达和表面定位，机制新颖可增强T细胞抗肿瘤功能并增敏免疫治疗。机构为研究机构得分较低，但热门ASO+免疫调控赛道及潜在克服耐药价值使其整体重要性中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10796", "id": "op3ECZ0B4z9FlvORyiZD", "source_drug_name": "antisense oligonucleotides", "title": "PCSK1 and PCSK7 orchestrate immune checkpoints to amplify anti-tumor immunity", "abstract_text": "Background: Immune-checkpoint receptors (ICPs) such as PD-1, CTLA-4, and TIGIT restrain T-cell activation and enable tumor immune evasion. Although ICP-targeting antibodies have transformed cancer therapy, many patients exhibit incomplete or transient responses, underscoring the need to identify upstream regulators that control ICP expression and function. Proprotein convertases (PCSKs) have recently emerged as modulators of immunity, but their roles in T-cell checkpoint regulation remain poorly defined.\nMethods: We investigated the functions of Furin and PCSK7 using CRISPR/Cas9-mediated gene deletion, antisense oligonucleotides (ASOs), overexpression systems, mouse knockout models, patient-derived tumor samples, paired PBMCs, and ex vivo T-cell activation assays. Immune-checkpoint expression and trafficking were assessed using flow cytometry, transcriptomic profiling, and imaging. Functional consequences were evaluated through cytokine secretion, proliferation assays, cytotoxicity measurements, chemotaxis analyses, and tumor-organoid co-culture systems.\nResults: Furin and PCSK7 emerged as complementary and essential regulators of ICP biology in T cells. Furin controls ICP expression at the transcriptional level, reducing mRNA abundance of PD-1, CTLA-4, and TIGIT upon deletion. In contrast, PCSK7 functions as a non-enzymatic chaperone, stabilizing newly synthesized ICPs and directing them to the cell surface. Loss of either convertase significantly diminished surface checkpoint levels and reduced the fraction of T cells co-expressing multiple inhibitory receptors. In human tumors and corresponding PBMC-derived T cells, decreased Furin or PCSK7 expression correlated with enhanced T-cell proliferation, cytokine release, and cytotoxic function. Organoid models, ex vivo patient tumor assays, and tumor-bearing mouse models demonstrated that targeting Furin and PCSK7 enhances the efficacy of chemotherapy and immunotherapy.\nConclusions: Furin and PCSK7 constitute key upstream regulators of immune checkpoints, controlling both transcriptional abundance and cell-surface availability through distinct mechanisms. Their inhibition enhances T-cell activation and anti-tumor function, representing a promising therapeutic strategy to potentiate immune responses and overcome resistance to current checkpoint-blocking therapies.", "source_company": "INSERM", "source_org_type": "研究机构", "row_number": 1037, "target_meta": "furin,PCSK7", "MOA_meta": "反义疗法"}, {"drug_name": "anti-PD-1 antibody", "company": "Pharmaron", "org_type": "公司", "target": "PD-1", "modality": "inhibitor", "importance_level": "中", "total_score": 58.5, "institution_score": 55, "track_score": 85, "milestone_score": 40, "field_heat_score": 80, "bonus_score": 0, "brief_reason": "药物为anti-PD-1抗体，靶向成熟免疫检查点PD-1，机制为经典ICI；Pharmaron作为CRO公司而非原创新药研发机构，得分中等，赛道为热门ICI但摘要仅为机制研究而非药物开发里程碑，整体重要性中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5309", "id": "g57M_5wBZznHJdnt_W3O", "source_drug_name": "anti-PD-1 antibody", "title": "Single-cell RNA-seq reveals insights into the effects of immune checkpoint inhibitors", "abstract_text": "Immune checkpoint inhibitors (ICIs) have demonstrated superior clinical efficacy, significantly prolonging patient survival across various cancers. However, the mechanisms by which ICIs modulate the immune system and memory function require continued exploration. Single-cell RNA sequencing (scRNA-seq) offers a powerful tool for oncology research and development. In this study, we performed scRNA-seq following treatment with an anti-PD-1 antibody in a murine colon adenocarcinoma model. Mice were inoculated with MC38 tumor cells, treated with ICIs, and subsequently re-challenged with the same tumor cells after tumor regression. Tumor-infiltrating lymphocytes (TILs) and peripheral blood mononuclear cells (PBMCs) were isolated and analyzed using scRNA-seq alongside flow cytometry. Single-cell suspensions were processed using the 10x Genomics Chromium platform. Single-cell libraries were constructed, sequenced, and pre-processed, including demultiplexing and mapping to the reference genome. Filtered data underwent dimensionality reduction and clustering, and cells were annotated into distinct populations based on classical markers. Within the tumor microenvironment (TME), we observed notable activation of CD4⁺ and CD8⁺ T cells, a reduction in immunosuppressive CD4⁺ Treg cells, and an increase in Th1 cells. Among CD8⁺ T cells, cytotoxic effector (Teff) and memory (Tem) subsets were elevated, indicating effective T-cell activation and enhanced anti-tumor immunity. Similarly, PBMC analysis revealed increased naive T cells and Th1 cells within the CD4⁺ population, while CD8⁺ T cells exhibited expansion of Tem subsets with a slight increase in Teff cells. Overall, our findings demonstrate that checkpoint blockade promotes durable anti-tumor responses through expansion and differentiation of memory T cells and enhanced immune cell infiltration at both genetic and peripheral levels. Anti-PD-1 therapy directly potentiated the tumor-killing capacity of TILs, promoting a shift toward subtypes favorable to tumor clearance. Concurrently, treatment reprogrammed T-cell subsets in PBMCs, improving differentiation potential and thereby strengthening effective anti-tumor immune responses.", "source_company": "Pharmaron", "source_org_type": "公司", "row_number": 1038, "target_meta": "PD1", "MOA_meta": "抑制剂"}, {"drug_name": "PRMT7 PROTAC", "company": "City of Hope National Medical Center", "org_type": "医院", "target": "PRMT7", "modality": "PROTAC", "importance_level": "中", "total_score": 58.5, "institution_score": 35, "track_score": 85, "milestone_score": 65, "field_heat_score": 75, "bonus_score": 3, "brief_reason": "PRMT7 PROTAC通过降解PRMT7上调MHC-I表达，增强AML的抗肿瘤免疫响应，机制新颖且针对免疫冷肿瘤有潜力。公司为知名癌症研究医院而非制药企业，得分较低，但PROTAC赛道和AML免疫治疗方向热度高，preclinical数据较扎实。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9597", "id": "lJ7M_5wBZznHJdnt_W3O", "source_drug_name": "PRMT7 PROTAC", "title": "Targeting PRMT7 elicits anti-AML immunity by promoting MHC-I expression", "abstract_text": "Protein arginine methylation regulates several cellular functions, including RNA splicing, translation and DNA damage repair. Protein arginine N-methyltransferase (PRMT) dysregulation is often seen in malignant hematopoiesis. PRMT7, the only type III PRMT, catalyzes monomethyl arginine (MMA) modification, but its role in leukemogenesis is elusive. Re-analysis of a previous genome-wide CRISPR/Cas9 screen revealed PRMT7 to be a crucial negative-regulator of MHC-I, prompting us to ask whether PRMT7 inhibition might promote anti-AML immunity. To assess the potential PRMT7 function in MHC-I presenting, we knocked out PRMT7 in human AML lines including THP-1 and Molm13 and assessed MHC-I levels. Relative to controls, PRMT7 KO remarkably upregulated MHC-I expression in both lines. We also observed MHC-I upregulation was also observed in both cell lines after treatment with the targeted degrader (PRMT7 PROTAC) ex-vivo at relatively low concentrations, while the same dose of either compound spared normal hematopoietic stem/progenitor (CD34+) cells. To confirm MHC-I dynamics in an MLL-AF9 mouse model, we generated a Prmt7 KO MLL-MA9 mouse model from hematopoietic-specific Prmt7 KO mice (Prmt7fl/fl;Vav1-Cre) and observed 2-fold upregulation of H-2Kb expression relative to WT MLL-AF9 cells.Given the critical role of MHC-I in CD8+ T cell activation, we next asked whether PRMT7 deletion would enhance CD8+ T cell responses. We evaluated human T cell killing effects in PRMT7-KO/-WT THP-1 or Molm13 cells cocultured with activated CD8+ T cells derived from healthy donors. Post-coculture, we found that PRMT7 KO AML cells were more susceptible to human T cell-mediated killing. In agreement, PRMT7 KO murine AML cells were more sensitive to mouse T cell-mediated killing using a coculture model of MA9 and syngeneic active CD8+ T cells. Moreover, following PRMT7 PROTAC pretreatment, THP1 cells were more sensitive to human T cells mediated killing in a coculture system of THP1 cells and CD8+ T cells.Next, to assess whether PRMT7 deletion impairs normal hematopoiesis, we analyzed total bone marrow cellularity and lineage frequency in Prmt7 KO (Vav1-Cre+) versus Prmt7-WT (Vav1-Cre-) mice via Cytek full-spectrum flow cytometry. While total BM cellularity was comparable, PRMT7 KO slightly increased the number of CD4⁺ or CD8⁺\nT cells. These results suggest that although PRMT7 function is likely dispensable for normal hematopoiesis, PRMT7 loss may have a modest effect on T cell proliferation or activation. In future studies, we will confirm whether PRMT7 inhibition promotes anti-tumor T cell activity in-vivo, and whether the underlying mechanism is via MHC-I regulation. Overall, we have shown that PRMT7 depletion or pharmacological inhibition enhances T cell function in part by upregulating MHC-I. These findings suggest that combining PRMT7 inhibitors with immunotherapy could be a promising strategy to overcome AML’s immune-cold properties.", "source_company": "City of Hope National Medical Center", "source_org_type": "医院", "row_number": 1049, "target_meta": "PRMT7", "MOA_meta": "PROTAC"}, {"drug_name": "SH6", "company": "Harvard Medical School", "org_type": "大学", "target": "SALL4", "modality": "degrader", "importance_level": "中", "total_score": 58.5, "institution_score": 35, "track_score": 85, "milestone_score": 65, "field_heat_score": 75, "bonus_score": 3, "brief_reason": "SH6为新型小分子SALL4降解剂（degrader），针对HMA治疗后异常激活的癌胚基因SALL4，可逆转MDS细胞HMA耐药并增强细胞毒性。机构为大学得分为中等，靶点+PROTAC-like降解机制赛道热度高，处于功能验证+体外/机制研究阶段具一定里程碑价值，总分中等偏上。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8575", "id": "qJ7M_5wBZznHJdnt_W3O", "source_drug_name": "SH6", "title": "HMA-induced oncogene reactivation as a driver of disease progression in MDS", "abstract_text": "Hypomethylating agents (HMAs), including azacitidine and decitabine, are widely used for high-risk myelodysplastic syndromes (MDS) and selected AML, yet most patients eventually relapse, and survival after HMA failure remains dismal. HMAs were long assumed to function primarily by reactivating tumor suppressor genes through DNA demethylation. However, our recent work demonstrated that HMAs paradoxically upregulate the oncofetal gene SALL4, and that this induction strongly correlates with inferior overall survival, challenging existing paradigms. Emerging data suggest that additional cancer-germline antigen genes (CGAGs) may be similarly reactivated, generating oncogenic programs that facilitate resistance and leukemic progression. To investigate this, we profiled paired pre- and post-HMA patient marrow samples using RNA-seq and methylation analysis. We observed consistent post-treatment upregulation and promoter hypomethylation of SALL4 and multiple CGAGs, including PIWIL2, HORMAD1, and DDX43. Induction was more pronounced in patients with progression or treatment failure. Functional studies in MDS cell models revealed that forced expression of SALL4 or selected CGAGs enhanced proliferation, impaired myeloid differentiation, and reduced sensitivity to HMAs. Conversely, shRNA-mediated depletion mitigated these phenotypes. CRISPR-DiR-driven locus-specific demethylation of SALL4 recapitulated HMA-associated activation and conferred a proliferative advantage, confirming a causal role for promoter demethylation in SALL4 reactivation. We next evaluated therapeutic vulnerabilities associated with this pathway. Treatment with a newly developed small-molecule SALL4 degrader (SH6) reduced viability in SALL4-high models and reversed HMA-induced resistance phenotypes. Combination treatment with HMA + SH6 demonstrated enhanced cytotoxicity compared to either agent alone. Ongoing studies are expanding this approach to additional CGAG targets and mapping resistant subpopulations using single-cell transcriptomic and epigenetic profiling. Together, these findings reveal that HMA therapy can trigger unintended activation of oncogenic CGAG programs that drive MDS progression. They support a new mechanistic framework in which treatment-induced epigenetic reawakening promotes malignant fitness, and they identify SALL4 and CGAGs as high-value biomarkers and therapeutic targets. This work motivates development of companion diagnostic strategies and combination regimens pairing HMAs with targeted degraders to prevent therapy-induced disease acceleration and improve patient outcomes.", "source_company": "Harvard Medical School", "source_org_type": "大学", "row_number": 1067, "target_meta": "SALL4", "MOA_meta": "降解剂"}, {"drug_name": "(Rp,Rp)-10", "company": "Nankai University", "org_type": "大学", "target": "STING", "modality": "other", "importance_level": "中", "total_score": 58.5, "institution_score": 25, "track_score": 75, "milestone_score": 85, "field_heat_score": 70, "bonus_score": 5, "brief_reason": "该药为手性优化的dCDN前药，靶向激活STING通路，在CT26模型中实现90%完全缓解并建立长期免疫记忆，preclinical数据强劲。机构为大学非商业实体得分较低，但STING激动剂赛道仍具较高关注度且有创新立体化学优化加分，总分处于中等水平。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10805", "id": "3Z7M_5wBZznHJdnt_W3O", "source_drug_name": "(Rp,Rp)-10", "title": "Chemically regulated STING-activating prodrugs of deoxyribose cyclic dinucleotides elicit robust immune activation and durable antitumor immunity", "abstract_text": "Background: Prodrugs derived from deoxyribose cyclic dinucleotides (dCDNs) exhibit enhanced cellular permeability, stability, and sustained STING activation. However, the impact of phosphotriester chirality on their bioactivity remains underexplored. This study systematically evaluates the stereochemistry-dependent pharmacology of alkyne-conjugated, esterase-sensitive dCDN prodrugs in vitro and in vivo. Methods: Three diastereoisomers of the dCDN prodrug: (Rp,Rp)-10, (Sp,Sp)-10, and (Rp,Sp)-10—were synthesized, purified by chiral HPLC, and confirmed by NMR and HRMS. Cellular uptake and stability were assessed in THP1-Lucia ISG cells. STING pathway activation was measured by IFN-β reporter assays and phospho-TBK1/IRF3 immunoblots. In vivo efficacy was evaluated in CT26 colon carcinoma-bearing BALB/c mice following intravenous administration. Immune memory was assessed by tumor rechallenge. Results: Among the isomers, (Rp,Rp)-10 exhibited the most potent STING activation (EC50 = 1.7 nM), superior cellular uptake, and prolonged TBK1/IRF3 signaling. In mice, all three prodrugs induced stronger systemic cytokine responses than ADU-S100 or the parent CDN 3′,3′-c-di-dAMP. In the CT26 model, (Rp,Rp)-10 achieved complete tumor regression in 9/10 mice (90% CR), significantly improved survival (p < 0.001), and established long-term immunological memory with 100% rejection upon rechallenge. No overt toxicity was observed. Conclusion: Phosphotriester chirality is a critical determinant of dCDN prodrug activity. (Rp,Rp)-10 represents a promising next-generation STING agonist with potent systemic antitumor immunity and durable therapeutic effects. These findings underscore the importance of stereochemical control in the rational design of STING-targeted cancer immunotherapies.", "source_company": "Nankai University", "source_org_type": "大学", "row_number": 1108, "target_meta": "STING", "MOA_meta": "其他"}, {"drug_name": "anti-Netrin-1 antibody", "company": "Cancer Research Center of Lyon", "org_type": "研究机构", "target": "Netrin-1", "modality": "inhibitor", "importance_level": "中", "total_score": 58.5, "institution_score": 40, "track_score": 65, "milestone_score": 75, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "靶向Netrin-1的中和抗体，通过阻断Netrin-1/UNC5B信号抑制淋巴管生成及肿瘤转移，实验室开发但已进入II期临床试验。机构为研究型，打分中等偏上；赛道为新型靶点抗体+转移机制有一定热度；里程碑包括动物模型显著减少肺转移及明确II期临床进展。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1535", "id": "C57M_5wBZznHJdnt_W7O", "source_drug_name": "anti-Netrin-1 antibody", "title": "Lymphangiogenesis in the uterine horns: Implication of the Netrin-1 and UNC5B signaling pathway in physiology and cancer", "abstract_text": "The lymphatic system consists of an open, unidirectional network of lymphatic vessels maintaining tissue homeostasis, intestinal absorption, immunosurveillance and immunomodulation. These vessels are lined by lymphatic endothelial cells (LECs). Lymphangiogenesis, defined as sprouting of new lymphatic vessels from pre-existing vessels or embryonic veins, is the main mechanism driving the formation and expansion of lymphatic networks during embryogenesis and in adults under physiological conditions.\nThis process involves numerous molecules, most notably VEGF-C, but also axon-guidance cues such as Netrins (Hu et al., 2024). Lymphangiogenesis shares many features with angiogenesis, which depends mainly on VEGF-A, but also Netrin-1. Netrin-1, acting through its receptor UNC5B, regulates vascular endothelial migration and branching, thereby stabilizing the vascular network (Lu et al., 2004).\nIn our laboratory, scRNAseq analysis of murine uterine horns revealed that Netrin-1 and UNC5B are specifically expressed by LECs. The lymphatic network of uterine horns has never been investigated, nor has the role of the Netrin-1 and UNC5B in lymphangiogenesis in general. We hypothesize that Netrin-1 and UNC5B contributes to lymphatic network development by regulating LEC migration and tubulogenesis. Our preliminary in vivo data describe the expression patterns of Netrin-1 and UNC5B during lymphatic development in murine uterine horns. UNC5B and Netrin-1 knockout models are being generated to define their functional roles. In vitro studies on human dermal LECs are assessing Netrin-1 effects on migration and tubulogenesis.\nThe lymphatic system is a key route for metastatic dissemination, notably in endometrial cancer (Donoghue et al., 2007). Uterine horns are continuously lined by the endometrium, suggesting that lymphatic vessels within uterine horns may provide a pathway for endometrial cancer cell dissemination. Although Netrin-1 is normally absent in adult tissues, it is re-expressed in tumors, where it promotes tumor progression. If Netrin-1 contributes to lymphangiogenesis in uterine horns, it may similarly modulate lymphatic vessel formation and thereby facilitate metastasis in endometrial cancer.\nConsistent with this, preliminary results showed that the neutralizing antibody anti-Netrin-1 in mice grafted with endometrial cancer cells significantly reduces lung metastases. The knockout models will help define how Netrin-1 and UNC5B could regulate lymphatic-dependent metastatic spread.\nThis project aims to characterize lymphangiogenesis in uterine horns and to define the roles of Netrin-1 and UNC5B in physiological and tumor contexts. Ultimately, this work may support new therapeutic applications for the anti-Netrin-1 antibody developed in our laboratory, currently in phase II clinical trial.", "source_company": "Cancer Research Center of Lyon", "source_org_type": "研究机构", "row_number": 1136, "target_meta": "NTN1", "MOA_meta": "抑制剂"}, {"drug_name": "CD47×TROP2 bsAb", "company": "Beth Israel Deaconess Medical Center", "org_type": "医院", "target": "CD47/TROP2", "modality": "bispecific antibody", "importance_level": "中", "total_score": 58.5, "institution_score": 35, "track_score": 85, "milestone_score": 55, "field_heat_score": 75, "bonus_score": 3, "brief_reason": "CD47×TROP2双抗为低亲和力CD47+肿瘤特异TROP2设计，属于热门双抗赛道且TROP2靶点热度高，但研发机构为医院学术中心而非biotech/pharma公司导致机构分较低。preclinical阶段显示强协同效应及优于lorlatinib的巨噬细胞杀伤活性，具有一定转化潜力。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5114", "id": "tp3ECZ0B4z9FlvORyiZD", "source_drug_name": "CD47×TROP2 bsAb", "title": "Unbiased discovery of novel macrophage-activating immunotherapies for ALK+ non-small cell lung cancer", "abstract_text": "Non-small cell lung cancer (NSCLC) represents ~85% of all lung cancer cases and remains one of the leading causes of cancer-related mortality in the United States. Approximately 3-7% of NSCLC patients harbor ALK rearrangements, most commonly the EML4-ALK fusion. Although ALK+ tumors initially respond well to ALK tyrosine kinase inhibitors (TKIs), patients still develop resistance. Lorlatinib, a third-generation ALK inhibitor, achieves ~76% response rates in treatment-naïve patients; however, a substantial proportion experience disease progression within a few years, highlighting the urgency for new therapeutic strategies. The tumor immune microenvironment is increasingly recognized as a key contributor to resistance. Tumor-associated macrophages (TAMs) are the dominant immune population infiltrating NSCLC and can promote tumor growth, survival, and immune evasion. Here, we aimed to identify novel therapeutic strategies to stimulate macrophages to eliminate ALK+ lung cancer cells.Using in vitro co-culture assays, we found that macrophages markedly protect ALK+ lung cancer cells from lorlatinib, making the cancer cells significantly less responsive compared to cells cultured alone. We found that blocking macrophage immune checkpoints, such as the CD47/SIRPa axis, could restore macrophage activation and promote phagocytosis of the ALK+ lung cancer cells. Since systemic administration of anti-CD47 antibodies can result in dose-limiting hematotoxicity, we therefore developed a high-throughput bispecific antibody (bsAb) engineering platform to leverage the benefits of targeting CD47 while increasing specificity to the tumor microenvironment. We generated a library of bsAbs targeting CD47 with a second arm binding well-known tumor antigens including EGFR, EpCAM, HER2, TROP2, FOLR1, Nectin-1, Nectin-4, PD-L1, and CD71. Using live-cell imaging, we evaluated macrophage-mediated cytotoxicity for each bsAb across three ALK+ NSCLC cell lines. Among all constructs tested, a bsAb incorporating a low-affinity CD47-binding domain and a TROP2-targeting domain showed the strongest anti-tumor activity, significantly reducing tumor growth over time. This bsAb enhanced macrophage phagocytosis and decreased tumor area more effectively than lorlatinib alone. Importantly, combining the CD47×TROP2 bsAb with lorlatinib produced synergistic anti-tumor effects, offering a promising strategy to overcome or delay resistance. Overall, our study has identified novel bispecific antibodies that may be highly active for ALK+ lung cancer and our findings could be translated to the clinic to benefit patients in the future.", "source_company": "Beth Israel Deaconess Medical Center", "source_org_type": "医院", "row_number": 1167, "target_meta": "CD47,TROP2", "MOA_meta": "双特异性抗体"}, {"drug_name": "PluraliNK cells", "company": "UT MD Anderson Cancer Center", "org_type": "医院", "target": "未披露", "modality": "CAR", "importance_level": "中", "total_score": 58.5, "institution_score": 35, "track_score": 85, "milestone_score": 70, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "PluraliNK cells为通用多受体工程NK细胞平台，通过CD3/iTCR和Fc受体双激活机制与现有mAb/TCE联合实现多靶点协同杀伤，靶点未明确披露。机构为顶级肿瘤医院非商业公司得分较低，但细胞治疗+多抗/TCE适配的热门赛道、双信号增强抗异质性及异体潜力、已启动临床试验使其整体重要性达中等偏上。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3692", "id": "fJ7M_5wBZznHJdnt_W7P", "source_drug_name": "PluraliNK cells", "title": "A universal multi-receptor NK cell platform engineered for synergistic combination with antibody and T-cell engager therapies", "abstract_text": "Background: Monoclonal antibodies (mAbs) and T-cell engagers (TCEs) redirect immune effector cells toward malignant targets, yet their efficacy is often limited by patient T- and NK-cell dysfunction. Conventional CAR strategies target a single antigen, requiring new construct design, GMP production, and separate regulatory pathways for each target. To combine the strengths of engager- and cell-based approaches, we developed PluraliNK cells, a universal multireceptor NK-cell platform activated through CD3/TCR- and Fc-dependent pathways. This enables redirection by any approved mAb or TCE without additional engineering, creating a flexible plug-and-play NK therapy.\nMethods: NK cells were engineered using two polycistronic vectors to express the full CD3 complex, IL-15 for cytokine support, high-affinity CD16A (F158V) for enhanced Fc engagement, and an invariant TCR α/β (iTCR) to stabilize CD3 and permit CD1d-restricted recognition. This dual-activation system allows PluraliNK cells to respond to CD3- or CD16-mediated signals and to pair with diverse mAbs or TCEs without further modification.\nResults: PluraliNK cells showed potent cytotoxicity across hematologic and solid tumor models when combined with approved mAbs (rituximab, trastuzumab) or TCEs (blinatumomab, glofitamab, elranatamab), consistently outperforming mAb/TCE monotherapy or unmodified NK cells. The platform supports simultaneous engagement by multiple antibodies or TCEs, enabling clearance of heterogeneous tumor populations and reducing antigen escape. Dual-input signaling enhanced activation, serial killing, and resistance to exhaustion, an advantage in solid tumors with spatial heterogeneity and lineage plasticity. Because PluraliNK activation depends on an external mAb or TCE, the system provides an additional safety layer compared with constitutively active CAR constructs. In NSG xenograft models, PluraliNK cells combined with mAbs or TCEs achieved superior tumor clearance, improved infiltration, and enhanced in vivo persistence without off-target toxicity.\nConclusions: This universal NK-cell platform enables multiantigen targeting and integration with existing mAbs and TCEs, addressing tumor heterogeneity and immune escape without requiring antigen-specific CAR redesign. A first-in-human clinical trial of PluraliNK cells with antibody therapy has been initiated.", "source_company": "UT MD Anderson Cancer Center", "source_org_type": "医院", "row_number": 1207, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "anti-IL-1β therapy", "company": "UT MD Anderson Cancer Center", "org_type": "医院", "target": "IL-1β", "modality": "inhibitor", "importance_level": "中", "total_score": 58.5, "institution_score": 45, "track_score": 70, "milestone_score": 65, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "药物针对IL-1β，通过阻断IL-1β-IL1R1交互在早期肺腺癌中显示抗肿瘤作用，主要机制为重塑肿瘤微环境并增强抗肿瘤免疫。机构为顶级癌症中心但属医院/学术型而非药企导致机构分不高，赛道为炎症靶点阻断在肿瘤早期的机制研究有一定热度，但仍处preclinical阶段且晚期无效限制里程碑价值，总分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1127", "id": "kJ7M_5wBZznHJdnt_W7P", "source_drug_name": "anti-IL-1β therapy", "title": "Spatial single-cell analysis reveals stage-dependent mechanisms of anti-IL-1β therapy in lung adenocarcinoma", "abstract_text": "Introduction: Lung adenocarcinoma (LUAD) is a leading cause of cancer mortality, with IL-1β-driven inflammation playing a central role in tumor progression. Although IL-1β blockade shows promising antitumor effects, its efficacy varies across tumor stages, and the mechanisms behind this stage-dependent response remain unclear. Here, we investigate how tumor-immune interactions and microenvironmental remodeling shape differential responses to anti-IL-1β therapy during LUAD progression.\nMethods: We performed spatial single-cell analysis of the immune microenvironment using Visium HD on human (10 adjacent normal, 17 AAH, 12 IAC) and mouse samples (21 adjacent normal, 57 hyperplasia, 13 IAC). Integrating these data with stage-matched scRNA-seq, we mapped IL-1β-IL1R1-mediated cell-cell interactions across LUAD stages. Long-term anti-IL-1β treatment was evaluated in two mouse models—C57BL/6 Kras^G12D (early: 4-14 weeks; late: 20-30 weeks) and 129S4 urethane-induced (early: 4-14 weeks; late: 30-40 weeks)—with efficacy and mechanisms assessed via scRNA-seq and Xenium 5K. Short-term treatments (0, 6, 30 weeks) in C57BL/6 Kras^G12D were performed to further explore mechanisms.\nResults: In human tissues, IL-1β-IL1R1 interactions (“IL-1βnets”) occurred primarily between myeloid cells and fibroblasts, epithelial, and endothelial cells, a pattern conserved in mouse tissues. Long-term anti-IL-1β treatment was effective only at the early stage. Early-stage scRNA-seq showed enhanced antitumor immunity and a marked reduction in interactions between IL1R1+ fibroblasts and IL-1β+ myeloid cells (monocytes, macrophages, cDCs, neutrophils), whereas late-stage tissues showed minimal changes. Spatial analysis with Xenium 5K confirmed reduced IL1R1+ cell fractions within IL-1βnets at the early stage, with IL-1βnet number and size largely unchanged. Short-term treatment at the early stage reduced interactions between IL1R1+ epithelial cells and neutrophils and attenuated NF-κB signatures in fibroblasts and epithelial cells; late-stage treatment had no significant effects.\nConclusion: Spatial single-cell profiling revealed the IL-1β-IL1R1 interaction landscape across LUAD progression in humans and mice. Anti-IL-1β therapy was effective in early-stage LUAD, disrupting key interactions between myeloid and fibroblast/epithelial cells, but was largely ineffective at later stages. These findings suggest that fibroblast and epithelial remodeling are critical determinants of stage-dependent anti-IL-1β efficacy.", "source_company": "UT MD Anderson Cancer Center\nThe University of Texas MD Anderson Cancer Center", "source_org_type": "医院", "row_number": 1222, "target_meta": "IL-1β", "MOA_meta": "抑制剂"}, {"drug_name": "(131I)I-FAPi 5", "company": "University of Copenhagen", "org_type": "大学", "target": "FAP", "modality": "RLT imaging agent", "importance_level": "中", "total_score": 58.5, "institution_score": 40, "track_score": 85, "milestone_score": 60, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "药物靶向FAP的二聚体放射性配体，使用131I标记，实现肿瘤靶向放射性核素治疗，在胶质母细胞瘤异种移植模型中显示出与177Lu对照药相当的肿瘤消退效果。机构为大学导致分数较低，但FAP-RLT赛道热度高、pan-tumor潜力强、预临床疗效清晰。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3917", "id": "U57ECZ0BZznHJdntvNYd", "source_drug_name": "(131I)I-FAPi 5", "title": "Efficacy of targeted radionuclide therapy Using 131I-FAPi dimers labeled via tetrazine ligation in a human glioblastoma xenograft model", "abstract_text": "The successful use of diagnostic radiotracers targeting the pan-tumor marker fibroblast activation protein (FAP) across numerous cancer types is well established; however, translating these agents into effective therapeutics remains challenging. Compared with monomeric FAP inhibitors (FAPi), FAPi dimers—containing two FAP-targeting vectors—exhibit enhanced tumor retention, resulting in higher tumor doses and encouraging preliminary clinical outcomes. Current therapeutic agents targeting FAP rely largely on chelator-based constructs, restricting their labeling to radiometals. To overcome this limitation, we previously developed FAPi dimers equipped for tetrazine ligation using the novel trans-cyclooctene T4CO, enabling selective formation of a single isomer. Our lead compound, (¹³¹I)I-FAPi 5, was synthesized with high yield and purity and evaluated in tumor-bearing animals, where it demonstrated therapeutic effects comparable to the established agent (¹⁷⁷Lu)Lu-DOTAGA-Glu(FAPi)₂. These findings suggest that (¹³¹I)I-FAPi 5 may offer a cost-effective and scalable radioligand therapy (RLT) option to meet the expanding demand for FAP-directed treatments.\n(¹³¹I)I-DUAL FAPi-5 was prepared by a two-step radiolabeling process using tetrazine ligation. First, a tetrazine-trimethylgermyl precursor was radioiodinated with ¹³¹I. The resulting synthon was purified by HPLC and subsequently clicked with the T4CO-FAPi derivative, achieving complete ligation within 10 minutes without requiring further purification. The therapeutic effect was investigated in U87-MG tumor-bearing mice. When the tumors reached 64±4mm3, the mice received a single intravenous injection of (131I)I-FAPi 5 (30 or 60 MBq), (177Lu)Lu-DOTAGA-Glu(FAPi)2 (30 MBq) or vehicle control (n=6/group). Tumor response was monitored every other day via caliper measurement and survival was assessed up to 70 days after the start of treatment. The mice were euthanized on reaching one of the predefined endpoint criteria.(¹³¹I)I-FAPi 5 was obtained in two steps with a final radiochemical yield of 60 ± 5% (n=4), radiochemical purity ≥98% (n=4). In U87-MG xenograft models, the tracer exhibited high and sustained tumor uptake. Treatment with (¹³¹I)I-FAPi 5 at both dose levels (30 MBq and 60 MBq) resulted in rapid tumor regression, with therapeutic performance comparable to that of (¹⁷⁷Lu)Lu-DOTAGA-Glu(FAPi)₂. Our dual-targeting FAPi compound labeled with ¹³¹I demonstrated robust tumor uptake and retention, with renal clearance as the primary excretion pathway. These findings confirm the therapeutic efficacy of this agent in preclinical tumor models, showing marked tumor regression and improved survival. Collectively, the results support the potential of this compound as an effective and accessible FAP-RLT candidate.", "source_company": "University of Copenhagen", "source_org_type": "大学", "row_number": 1244, "target_meta": "FAP", "MOA_meta": "其他"}, {"drug_name": "64Cu-RAX301", "company": "Affiliated Hospital of North Sichuan Medical College", "org_type": "医院", "target": "PSMA", "modality": "RLT imaging agent", "importance_level": "中", "total_score": 58.5, "institution_score": 35, "track_score": 75, "milestone_score": 75, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "64Cu-RAX301为高亲和力PSMA PET显像剂，较68Ga-PSMA-11展现更强肿瘤摄取、更优对比度和额外小病灶检出能力。医院主导的first-in-human研究已显示显著诊断改进价值，但机构非头部药企导致总体评分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8589", "id": "mlXM_5wBX1NQZOEH-LK6", "source_drug_name": "64Cu-RAX301", "title": "Development and clinical evaluation of ⁶⁴Cu-RAX301: A next-generation PSMA PET tracer for enhanced detection of metastatic prostate cancer", "abstract_text": "Prostate-specific membrane antigen (PSMA) PET imaging is widely used for diagnosing and staging prostate cancer, yet the currently approved ⁶⁸Ga- and ¹⁸F-labeled tracers are limited by short half-lives and high urinary excretion, which can obscure small pelvic lesions. To overcome these challenges, ⁶⁴Cu-RAX301 was developed as a high-affinity PSMA PET tracer designed for improved biochemical stability and extended imaging flexibility. The RAX301 precursor and its natCu-RAX301 analog were synthesized with high purity, and radiolabeling with ⁶⁴Cu was optimized to achieve high molar activity (≥2000 mCi/μmol) and radiochemical purity (>95%), and remaining stable for over 48 hours post-formulation. Surface plasmon resonance revealed sub-picomolar binding affinity (Kd < 1 pM) for both the precursor and natCu-RAX301, markedly stronger than PSMA-617 (22 pM). Consistent with this, cell-based assays showed two-fold higher affinity, 1.5-fold greater uptake, and four-fold higher internalization compared with ⁶⁴Cu-PSMA-617 (≈80% vs. ≈20%). In LNCaP xenograft mice, ⁶⁴Cu-RAX301 demonstrated intense and persistent tumor uptake, with tumor-to-muscle ratios exceeding one hundred at 4 hours post-injection. PET imaging in Macaca fascicularis revealed primarily renal clearance with minimal uptake in other organs. In a first-in-human study of ten patients with metastatic castration-resistant prostate cancer (mCRPC), sequential PET/CT scans were performed first with ⁶⁸Ga-PSMA-11 (5 mCi; imaging at 1 hour post-injection) and then with ⁶⁴Cu-RAX301 (5 mCi; imaging at 4 and 24 hours post-injection), separated by 1-7 days. ⁶⁴Cu-RAX301 detected all lesions identified by ⁶⁸Ga-PSMA-11 while providing higher lesion uptake and superior tumor-to-background contrast. Notably, ⁶⁴Cu-RAX301 revealed numerous additional small lesions at various sites, including pelvic lymph node metastases that were frequently missed by ⁶⁸Ga-PSMA-11 due to early bladder activity. The tracer exhibited an excellent safety profile with no significant adverse events. Collectively, these preclinical and early clinical findings demonstrate that ⁶⁴Cu-RAX301 possesses ultra-high PSMA affinity, favorable pharmacokinetics, and enhanced lesion visualization compared with ⁶⁸Ga-PSMA-11, supporting its potential as a next-generation PSMA PET imaging agent with improved sensitivity and diagnostic performance in metastatic prostate cancer. Ongoing clinical studies aim to further define its diagnostic impact and broader clinical utility.", "source_company": "Affiliated Hospital of North Sichuan Medical College", "source_org_type": "医院", "row_number": 1266, "target_meta": "PSMA", "MOA_meta": "其他"}, {"drug_name": "ATH-409", "company": "Atheron Therapeutics, Ltd.", "org_type": "公司", "target": "ITK", "modality": "inhibitor", "importance_level": "中", "total_score": 58.5, "institution_score": 45, "track_score": 75, "milestone_score": 55, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "ATH-409为高选择性共价ITK抑制剂，通过促进Th1分化、减轻T细胞耗竭实现免疫调控抗肿瘤效应，靶点ITK在肿瘤免疫治疗中具有一定创新性。机构为小型/未知biotech公司，得分一般；赛道为选择性激酶抑制剂结合T细胞免疫调节，热度中等偏上；数据限于体外和体内模型（CT26），处于早期preclinical阶段。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9629", "id": "KlXM_5wBX1NQZOEH-LK6", "source_drug_name": "ATH-409", "title": "Identification of a highly selective ITK inhibitor which promotes Th1 differentiation and alleviates T cell exhaustion in vitro and in vivo", "abstract_text": "ITK is a member of the TEC family of kinases, expressed in T, NK, and mast cells. ITK plays important roles in TCR signaling and T cell differentiation. Following TCR stimulation, ITK is recruited to the cell membrane and then leads to phosphorylation and activation of PLCγ1. ITK knockout mice show defects in Th2 differentiation, while retaining the ability to differentiate into Th1 cells, a phenomenon known as Th1 skewing. It is generally accepted that Th1 cells are the primary Th cell subtype associated with tumor elimination. ITK and RLK double knockout in T cells has a more substantial signaling defect, resulting in a profound loss of normal T cell function. Thus, it holds great therapeutic promise to treat cancer with selective ITK inhibitors while sparing RLK.Here, we report that ATH-409 is a highly selective, covalent ITK inhibitor with an IC50 of < 5 nM and more than 300-fold selectivity against RLK and at least 100-fold selectivity against the remaining 10 cysteine-containing kinases. In the kinase panel assay involving 430 kinases, ATH-409 exhibits inhibitory activity against less than 5 of these kinases, with an IC₅₀ selectivity of at least 60-fold for all of the non-target kinases. ATH-409 potently suppresses ITK-mediated phosphorylation of PLCγ1 and TCR activation-induced IL2 release in PBMCs. At high concentrations, ATH-409 exerts an anti-proliferation effect on human primary T cells, while showing no impact on T cell viability. Under both polarizing and non-polarizing conditions, ATH-409 does not affect the production of Th1 cytokines, but decreases the release of Th2 cytokines. Additionally, ATH-409 attenuates the occurrence of T cell exhaustion. ATH-409 alone does not suppress the proliferation of CT26 cells in vitro, but does inhibit CT26 tumor growth in vivo, indicating that the anti-tumor effect of ATH-409 is achieved through regulating the immune system. In in vivo model, the ITK occupancy increases with the elevation of ATH-409. Furthermore, when ATH-409 is combined with PD-1 antibody and CTLA-4 antibody, the inhibitory effect on CT26 tumors is further enhanced. Analysis of tumor-infiltrating lymphocytes (TILs) reveals that under the combination treatment, the proportion of Th1 cells in tumors increases and T cell exhaustion is alleviated, which is consistent with the phenomena observed in in vitro experiments.", "source_company": "Atheron Therapeutics, Ltd.", "source_org_type": "公司", "row_number": 1271, "target_meta": "ITK", "MOA_meta": "抑制剂"}, {"drug_name": "HSC00189", "company": "Xizang Haisco Pharmaceutical Co. Ltd", "org_type": "公司", "target": "CDH6/FOLR1", "modality": "bispecific ADC", "importance_level": "中", "total_score": 58.5, "institution_score": 55, "track_score": 85, "milestone_score": 40, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "HSC00189为新型双特异性ADC同时靶向CDH6和FOLR1，用于卵巢癌治疗；Haisco为国内制药企业非头部，赛道热门但仅preclinical阶段无具体数据披露导致里程碑分较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11410", "id": "blXM_5wBX1NQZOEH-LG5", "source_drug_name": "HSC00189", "title": "Preclinical characterization of HSC00189, a novel bispecific ADC targeting cadherin-6 (CDH6) and folate receptor alpha (FOLR1) for the treatment of ovarian cancer", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Xizang Haisco Pharmaceutical Co. Ltd", "source_org_type": "公司", "row_number": 1288, "target_meta": "CDH6,FOLR1", "MOA_meta": "抗体偶联药物"}, {"drug_name": "MTA-cooperative PRMT5 inhibitors", "company": "Panome Bio", "org_type": "公司", "target": "PRMT5", "modality": "inhibitor", "importance_level": "中", "total_score": 58, "institution_score": 45, "track_score": 85, "milestone_score": 40, "field_heat_score": 75, "bonus_score": 0, "brief_reason": "药物为针对PRMT5的MTA-cooperative抑制剂，主要用于MTAP缺失肿瘤的合成致死策略，该靶点和机制在精准肿瘤学中热度较高。Panome Bio作为新兴代谢组学服务公司而非药物研发主体，本摘要仅为其开发伴随诊断代谢物检测方法，临床开发阶段早期且非直接推进药物，故综合重要性中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9213", "id": "O1XM_5wBX1NQZOEH-LK6", "source_drug_name": "MTA-cooperative PRMT5 inhibitors", "title": "A multiplexed LC-MS/MS metabolite assay to enable patient stratification and pharmacodynamic monitoring for MTA-cooperative PRMT5 inhibitors", "abstract_text": "The development of Protein Arginine Methyltransferase 5 (PRMT5) inhibitors, particularly MTA-cooperative agents that selectively target MTAP-deleted cancers, has created an urgent need for robust biomarkers to identify target patient populations and confirm pharmacodynamic (PD) target engagement. The purpose of this study was to develop and apply a highly sensitive, multiplexed liquid chromatography-mass spectrometry (LC-MS/MS) assay to quantify key PRMT5-related metabolites such as methylthioadenosine (MTA), symmetric dimethylarginine (SDMA), S-adenosylmethionine (SAM), and asymmetric dimethylarginine (ADMA), as well as interacting metabolites in the folate cycle, methionine cycle, and polyamine metabolism. The developed multiplexed LC-MS/MS method enables simultaneous quantification of MTA, SDMA, SAM, and SAH, and 12 other related metabolites from cell lysates, tumor tissue, and biofluids. The assay leverages isotopically labeled internal standards and fragment ion monitoring for robust quantitation and resolution of key PRMT biomarkers ADMA (Type I PRMTs, e.g., PRMT1) and SDMA (PRMT5). We then applied this assay to matched adenocarcinoma tumor and normal adjacent tissue (NAT) specimens from n=6 human patients. The results showed statistically significant (p<0.05) increases in SAM and MTA as well as S-adenosylhomocysteine (SAH) levels in the tumor. The elevated MTA levels was driven by a subset of patients, suggesting these individuals have MTAP-deleted tumors. SAM and SAH are reactants and products, respectively, of PRMT5 and Type I PRMTs like PRMT1. The elevation of SAM and SAH in the tumor suggests elevated PRMT activity. In examining SDMA and ADMA levels, we found that ADMA (PRMT1 biomarker) was elevated by 40% in the tumor, while SDMA (PRMT5 biomarker) showed less than 20% elevation. In total, these data demonstrate the utility of the developed metabolite assay for the development of PRMT5 therapies. The differences between tumor and NAT metabolite profiles are consistent with upregulated PRMT1 (or another Type I PRMT) in the tumor, leading to elevated ADMA, SAM, and SAH. PRMT5, on the other hand, is likely inhibited by elevated MTA levels in the MTAP-deleted tumors, making them more susceptible to MTA-cooperative PRMT5 inhibitors, despite not significantly increasing SDMA levels in the tumor.", "source_company": "Panome Bio", "source_org_type": "公司", "row_number": 30, "target_meta": "PRMT5", "MOA_meta": "抑制剂"}, {"drug_name": "PORCN inhibitor", "company": "Tailor Bio Ltd", "org_type": "公司", "target": "PORCN", "modality": "inhibitor", "importance_level": "中", "total_score": 58, "institution_score": 45, "track_score": 65, "milestone_score": 70, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "靶向PORCN抑制Wnt信号通路，Tailor Bio为英国小型新兴biotech，机构实力一般；赛道为小分子抑制剂+生物标志物指导，Wnt通路有一定热度但临床响应有限，此研究提供CIN签名作为强预测标志物并meta分析支持，preclinical证据扎实且有临床回顾验证，建议食管癌/胃癌进一步开发。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9846", "id": "-1XM_5wBX1NQZOEH-LC5", "source_drug_name": "PORCN inhibitor", "title": "Wnt-driven chromosomal instability as a biomarker for PORCN inhibition", "abstract_text": "Targeting Porcupine (PORCN), a key regulator of the WNT-signalling pathway, has shown therapeutic potential in multiple cancers. However, clinical responses to PORCN inhibitors have so far been limited despite strong target engagement data and a favourable safety profile. Given that Wnt signaling can drive tumorigenesis by inducing chromosomal instability (CIN), we hypothesised that CIN signatures might serve as a novel predictive biomarker to improve PORCN inhibitor response rates. Using a combination of CIN signatures capturing diverse Wnt-driven CIN processes including replication stress, error-prone non-homologous end joining repair, and whole genome duplication, we established proof-of-concept of a biomarker predictive of PORCN inhibition response. We found that CIN signature activity significantly correlated with both knockdown and pharmacological inhibition of PORCN across 180 and 24 cancer cell lines, respectively (Kendall’s Tau=-0.16, P-value=0.001,Tau=-0.22, P-value=0.065). We performed a meta-analysis of 25 studies of in vivo patient-derived or cell-line xenografts treated with PORCN inhibitors, and found that biomarker activity was quantitatively associated with response to PORCN inhibition, (CIN signature activity versus tumour over control ratio, Pearson’s R=-0.66, P-value=0.009). Using these data to determine an optimised threshold for clinical application (specificity=100%, 95%CI:54.07%-100% and sensitivity=100%, 95%CI:29.24%-100%), we showed concordance between predicted and observed efficacy in previous PORCN inhibitor clinical trials. The quantitative nature of the CIN signature biomarker offers an opportunity to widen the therapeutic index of existing clinical stage PORCN inhibitors and analysis of biomarker prevalence across 6,335 patient tumours from The Cancer Genome Atlas study identifies esophageal and gastric cancers as optimal indications for future clinical development.", "source_company": "Tailor Bio Ltd", "source_org_type": "公司", "row_number": 305, "target_meta": "PORCN", "MOA_meta": "抑制剂"}, {"drug_name": "Cxcl10 LNP", "company": "West Virginia University School of Medicine", "org_type": "大学", "target": "未披露", "modality": "mRNA", "importance_level": "中", "total_score": 58, "institution_score": 35, "track_score": 85, "milestone_score": 65, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "Cxcl10 mRNA-LNP作为遗传佐剂通过增强T细胞募集和CD8+ T细胞浸润显著提升双免疫检查点抑制剂在黑色素瘤模型中的疗效和长期生存，但靶点未明确披露。机构为大学得分较低，但mRNA佐剂结合ICI的热门赛道、较强的动物模型数据和转移瘤改善潜力带来较高综合热度。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9691", "id": "5FXM_5wBX1NQZOEH-LK6", "source_drug_name": "Cxcl10 LNP", "title": "A Cxcl10 mRNA-LNP adjuvant enhances immune checkpoint inhibitor responses in melanoma models", "abstract_text": "Immunotherapies have become standard of care in the treatment of melanoma; however, about 50% of patients are immunotherapy resistant. This can be caused by an immunosuppressive tumor microenvironment that has a low infiltration of immune cells, especially T cells. Tumors with high T cell infiltration demonstrate better responses to immune checkpoint therapy, making modulation of the tumor microenvironment to enhance T cell recruitment and activation a critical unmet need. In this study, we hypothesize that using an mRNA encoded “genetic adjuvant” can increase the infiltration of T cells into the tumor microenvironment and improve immunotherapy response. The chemokine CXCL10 plays a key role in T cell recruitment and activation, signaling via the CXCR3 receptor expressed by activated T cells. Consistent with this mechanism, analysis of melanoma patient serum samples showed significantly higher Cxcl10 levels in immunotherapy responders compared to non-responders. To directly enhance CXCL10, we developed a Cxcl10-encoded mRNA lipid nanoparticle (Cxcl10 LNP). A significant increase in CXCL10 levels in the sera and inguinal lymph nodes of C57BL/6J wild-type mice was observed post intramuscular administration of Cxcl10 LNP. Our data shows that intramuscular injection of Cxcl10 LNP significantly reduced the volume of established subcutaneous B16F10 murine melanoma tumors. Cxcl10 LNP treatment lead to a significant increase of CD8+ T cells within the tumor microenvironment at 48 hours assessed by flow cytometry and intravital imaging. Phenotypic profiling further revealed significant increases of TRP-2 tumor specific CD8+ T cells and CD107a+ cytotoxic effector CD8+ T cells 48hrs post intramuscular administration of Cxcl10 LNP. When combined with dual anti-PD-1 and anti-CTLA-4 immune checkpoint inhibitor antibodies, Cxcl10 LNP improved long-term survival and significantly decreased subcutaneous tumor growth, with 20% of mice tumor-free at day 100. Moreover, in our spontaneous metastatic melanoma model, mice received Cxcl10 LNP 24h post primary tumor resection followed by dual anti-PD-1 and anti-CTLA-4 immune checkpoint inhibitors for a total of 3 doses. Adjuvating immune checkpoint inhibitors with Cxcl10 LNP significant reduced lung and lymph node metastasis, with 80% of mice showing no detectable metastases. These findings demonstrate that using Cxcl10 LNP is an effective genetic adjuvant that enhances CD8+ T cell infiltration and cytotoxic function, resulting in improved efficacy of immune checkpoint inhibitors and reducing tumor burden and metastases.", "source_company": "West Virginia University School of Medicine", "source_org_type": "大学", "row_number": 635, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "MTA-cooperative PRMT5 inhibitors", "company": "Fralin Biomedical Research Institute", "org_type": "研究机构", "target": "PRMT5", "modality": "inhibitor", "importance_level": "中", "total_score": 58, "institution_score": 35, "track_score": 85, "milestone_score": 65, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "药物为针对PRMT5的MTA-cooperative抑制剂，靶向MTAP缺失肿瘤的合成致死机制，赛道热度高（PRMT5+合成致死+热门肿瘤）。机构为研究机构非商业公司、仍处preclinical机制研究阶段导致综合评分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3028", "id": "MlXM_5wBX1NQZOEH-LO6", "source_drug_name": "MTA-cooperative PRMT5 inhibitors", "title": "Multi-omics characterization of PRMT5 inhibition identifies vulnerabilities for combination therapy in MTAP-deleted cancers", "abstract_text": "Homozygous deletion of CDKN2A on chromosome 9p21 is the most frequent genomic loss in cancer and often extends into the adjacent MTAP gene. This co-deletion occurs in ~10% of tumors (>200,000 cases annually in the U.S) and is particularly enriched in aggressive malignancies such as glioblastoma (GBM), malignant peripheral nerve sheath tumors (MPNST), pancreatic ductal adenocarcinoma (PDAC), and non-small cell lung cancer (NSCLC). In these tumors, MTAP loss leads to intracellular accumulation of its substrate methylthioadenosine (MTA), which partially inhibits protein arginine methyltransferase 5 (PRMT5) by competing with its methyl donor S-adenosyl-methionine (SAM) at the active site, reducing its ability to symmetrically dimethylate arginine residues (SDMA). This creates a synthetic-lethal dependence on residual PRMT5 activity and has driven the development of MTA-cooperative PRMT5 inhibitors, which show encouraging preclinical activity and single-agent response rates of 21-29% in early clinical trials in the advanced, refractory setting. We therefore hypothesized that defining the molecular consequences of PRMT5 inhibition could guide patient stratification and inform rational combination strategies capable of enhancing therapeutic efficacy and preventing resistance. To test this, we performed multi-omics profiling, including short- and long-read transcriptomics and whole-cell proteome mass spectrometry, across MTAP-deleted NSCLC, GBM, and PDAC models, integrating these data with in-house and publicly available datasets to define PRMT5-dependent methyl events and their downstream molecular consequences. Transcriptomic and proteomic analyses revealed strong and consistent pathway-level alterations across models following PRMT5 inhibition, including activation of MAPK signaling, a compensatory program validated to synergize with PRMT5 inhibitors in vitro and in vivo. Across eight distinct PRMT5 methyl-enrichment mass spectrometry studies, we identified 180 PRMT5 substrates enriched mainly for proteins involved in RNA metabolism and pre-mRNA splicing, including multiple snRNP-associated components of the spliceosome. We therefore examined the splicing consequences of PRMT5 inhibition and observed widespread increases in intron retention and reductions in exon skipping, with enrichment of splicing alterations in transcripts involved in DNA damage repair across models. Overall, this study provides a comprehensive substrate map of PRMT5 and characterizes the transcriptional, proteomic, and splicing programs activated upon its inhibition across MTAP-deleted GBM, NSCLC, and PDAC models. These findings highlight pathway and splicing-associated vulnerabilities as targets for rational combination strategies and establish a mechanistic framework to guide biomarker development and future therapeutic exploration.", "source_company": "Fralin Biomedical Research Institute", "source_org_type": "研究机构", "row_number": 686, "target_meta": "PRMT5", "MOA_meta": "抑制剂"}, {"drug_name": "CAR-T cells", "company": "Stanford University", "org_type": "大学", "target": "未披露", "modality": "CAR", "importance_level": "中", "total_score": 58, "institution_score": 35, "track_score": 85, "milestone_score": 65, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "该工作聚焦CAR-T细胞的供体异质性评估及遗传扰动筛选方法学优化，未披露具体靶点或药物实体。大学机构+热门细胞治疗赛道+高效平台技术开发具有一定preclinical方法学里程碑价值，但缺乏具体药物推进亮点。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9412", "id": "Y57ECZ0BZznHJdntvNYd", "source_drug_name": "CAR-T cells", "title": "Assessing donor heterogeneity in CAR-T cells with massively parallel mixed lymphocyte reactions", "abstract_text": "Donor heterogeneity is a major source of variation in CAR-T cell functions which leads to inconsistencies in both clinical efficacy and pre-clinical studies to enhance CAR-T cell functions. However, assessing T cell donor heterogeneity with a large sample size is costly and time-consuming. Here, we developed a Massively Parallel - Mixed Lymphocytes Reaction (MP-MLR) assay that allows pooling and simultaneously testing of CAR-T cells from multiple human donors. Combining with pooled genetic perturbation technologies, we conducted pooled screening in more than 50 T cell donors for enhanced CAR-T cell proliferation under repetitive tumor stimulations, with a library of candidate genetic perturbations proposed to enhance CAR-T or T cell functions. While we identified genetic perturbations with consistent effect on CAR-T cells across donors, the majority of perturbations showed various levels of donor dependencies, and this observation was confirmed with arrayed validation of selected perturbations on specific donors. Furthermore, we performed multi-parameters pooled screening in-vitro and in-vivo for systematic discovery of generalizable and donor specific genetic perturbations enhancing CAR-T cell pre-clinical therapeutic efficacies. Overall, we presented an efficient and cost-effective strategy for assessing donor variabilities in CAR-T cells, predicting patient specific effects of genetic perturbations on CAR-T cells efficacies, and potentially identifying of personalized optimal genetic perturbation for enhancing CAR-T cell functions.", "source_company": "Stanford University", "source_org_type": "大学", "row_number": 758, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "PHOX2B epitope-encoding mRNA-lipid nanoparticle (LNP) vaccine", "company": "Children's Hospital of Philadelphia", "org_type": "医院", "target": "PHOX2B", "modality": "mRNA", "importance_level": "中", "total_score": 58, "institution_score": 35, "track_score": 85, "milestone_score": 65, "field_heat_score": 75, "bonus_score": 3, "brief_reason": "该疫苗针对神经母细胞瘤关键癌基因PHOX2B编码表位，通过mRNA-LNP增强PC-CAR T细胞持久性和功能。机构为医院得分为35分，mRNA+CAR-T booster赛道热度高且有IND-enabling数据及临床试验计划，综合获中重要性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1778", "id": "pp7M_5wBZznHJdnt_W3O", "source_drug_name": "PHOX2B epitope-encoding mRNA-lipid nanoparticle (LNP) vaccine", "title": "Epitope-encoded mRNA-LNP vaccine to enhance anti-tumor potency and persistence of PHOX2B peptide-centric CAR T cells", "abstract_text": "Background: A Phase 1/1b clinical trial testing peptide-centric chimeric antigen receptor (PC-CAR) T cells that recognize a peptide derived from the major neuroblastoma oncoprotein PHOX2B presented in the context of HLA-A*24:02 and 20 other HLA-A alleles is showing early signs of safety and efficacy (NCT07007117). Anticipated barriers to durable cures include poor persistence and a hostile tumor immune microenvironment (TIME). We hypothesize that persistence and potency can be enhanced, without compromising safety, through the deployment of a “CAR boosting” PHOX2B epitope-encoding mRNA-lipid nanoparticle (LNP) vaccine.\nMethods: We established a screening platform to test various PHOX2B mRNAs and LNP designs, and here report on the prioritized formulation: a nucleoside-modified PHOX2B 9mer monomer encapsulated by FDA-approved LNP SM-102. In parallel, we established a genetically engineered mouse model (GEMM) of NB to deploy our PHOX2B epitope mRNA-LNP vaccination strategy in vivo.\nResults: A24+ healthy donor or NB patient monocyte-derived dendritic cells (moDCs) treated with vaccine exhibited log-fold higher PHOX2B 9mer presentation compared to tumor cells and upregulated T cell costimulatory ligands CD80/86 and CD40. PC-CAR T cells exposed to vaccine-treated moDCs had significantly increased proliferation, polyfunctionality, and migratory markers compared to co-cultures with HLA matched NB cell lines. Moreover, vaccine-treated moDCs enriched central, effector, and/or stem cell memory PC-CAR T cell immunophenotypes (donor/patient-dependent) compared to tumor-induced PD1hiCD39hi terminal effectors. PC-CAR T cells primed with vaccine-treated moDCs maintained significantly greater cytotoxicity in serial tumor rechallenges. A comprehensive characterization of the immunobiological effects of mRNA-LNP on DC and PC-CAR T cell function using O-link proteomics and transcriptional profiling are ongoing and will be reported.\nGEMM-derived allografts faithfully recapitulate human disease and express a chimeric HLA-A*24:02/H-2Kb MHC that presents a conserved PHOX2B 9mer. Murine (m)PC-CAR T cells engineered with clinical scFv conjoined to murine 41BB- or CD28-CD3ζ were polyfunctional and cytotoxic against A24/H-2Kb allografts. Vaccine-treated A24/H-2Kb knock-in mice presented PHOX2B 9mer by DCs in spleen and lymph nodes, activating PC-CAR T cells. Comprehensive in vivo evaluation of mPC-CAR-T expansion, memory formation, and anti-tumor potency with TIME spatialomic profiling are ongoing and will be reported.\nConclusion: These IND-enabling studies will inform our clinical vaccine dosing strategy with the recommended Phase 2 PC-CAR T cell dose in an upcoming trial amendment. This CAR boosting vaccine may not only improve efficacy of PC-CAR T cells for NB but also guide mRNA-LNP enhancement strategies for other adoptive cellular therapies.", "source_company": "Children's Hospital of Philadelphia", "source_org_type": "医院", "row_number": 1064, "target_meta": "PHOX2B", "MOA_meta": "其他"}, {"drug_name": "LIN-T", "company": "Umeå University", "org_type": "大学", "target": "未披露", "modality": "mRNA", "importance_level": "中", "total_score": 58, "institution_score": 35, "track_score": 85, "milestone_score": 65, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "LIN-T为脂质整合标签优化的LNP平台，用于靶向mRNA递送，实现Her2+等细胞的特异递送和翻译；大学机构基础分较低，但mRNA+LNP靶向递送为当前高热度赛道，前临床展示多靶点有效性和可扩展生产潜力。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5551", "id": "-Z7M_5wBZznHJdnt_W3O", "source_drug_name": "LIN-T", "title": "LIN-T (lipid integrated tag): An optimized tag-lipid nanoparticle design for targeted therapeutic mRNA delivery", "abstract_text": "Background: Lipid nanoparticles (LNPs) are the leading platform for mRNA delivery, but targeted delivery remains challenging. Factors such as lipid composition, particle size, charge, and ionizable lipid selection influence biodistribution, cellular uptake, and mRNA translation. Antibody-decorated LNPs offer a strategy to expand therapeutic applications.\nApproach: Conventional antibody decoration methods, such as post-formulation conjugation (click or maleimide chemistry), fusion proteins, or site-specific lipid conjugation, require chemical modification of antibodies. Modifications that can compromise stability and increase aggregation risk. To address this, we developed a modular system using a short peptide tag integrated into the LNP surface, enabling rapid antibody attachment via a bispecific antibody design without chemical conjugation.\nInnovation: Our 9-amino-acid tag (optimized in our recent Nature com. publication: PMID 39500897) binds an scFv (single-chain variable fragment) domain with picomolar affinity. The tag shows minimal immunogenicity risk in vitro and in vivo, likely as the tag is shielded upon binding. We demonstrate two complementary strategies for tag incorporation on the LNP:\n1.\tProtein-based: Recombinant inert ApoE (ApoEi)-fusion tag for rapid coating of preformed LNPs.2.\tSynthetic lipid-based: DSPE-PEG-tag conjugate integrated during LNP assembly.\nBoth approaches preserve tag accessibility and enable efficient antibody decoration. The ApoEi-tag design uniquely also blocks ApoE-LDL receptor interactions, and we can display that this reduces liver tropism.\nResults: Using this platform, we achieved targeted mRNA delivery and translation in Her2+, CD40+, CD3+, and CD20+ cells. The synthetic DSPE-PEG-tag supports scalable, GMP-compatible production, and the ApoEi-based method enables a rapid tool for research purposes. Our human scFv can be formatted into a classical Morrison bispecific design and expressed in CHO cells at titers >8 g/L.\nConclusion: These strategies provide a versatile framework for precision-targeted mRNA delivery, supporting customizable LNP therapeutics within for example oncology and autoimmune diseases.", "source_company": "Umeå University", "source_org_type": "大学", "row_number": 1125, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "CH41", "company": "Emory University", "org_type": "大学", "target": "CHD4", "modality": "inhibitor", "importance_level": "中", "total_score": 57.5, "institution_score": 35, "track_score": 75, "milestone_score": 70, "field_heat_score": 65, "bonus_score": 5, "brief_reason": "CH41为首创CHD4共价小分子抑制剂，通过稳定CHD4并诱导NuRD复合物解离，破坏胶质母细胞瘤DNA修复和转录调控，重敏替莫唑胺耐药细胞。大学机构得分较低，但首创机制+难成药靶点+胶质母细胞瘤未满足需求带来较高赛道与里程碑价值。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6517", "id": "v1XM_5wBX1NQZOEH-LK6", "source_drug_name": "CH41", "title": "First-in-class stabilizing inhibitor of CHD4 that traps and disassembles the NuRD complex", "abstract_text": "CHD4, the catalytic core of the NuRD complex, regulates chromatin remodeling, transcriptional repression, and DNA repair. Its overexpression in glioblastoma correlates with poor prognosis, yet CHD4 has remained undruggable. Employing a novel cell target engagement strategy, we identified CH41, a first-in-class small molecule that covalently engages cystine residues in the CHD4 chromodomain. The compound stabilizes CHD4 on chromatin, blocks its remodeling activity, and induces NuRD complex dissociation and proteasomal degradation. MICRO-TAG® cellular target engagement assay system applied in both discovery and validation stages, confirms direct CHD4 binding and real-time intracellular stabilization consistent with mechanistic trapping. CH41 disrupts CHD4 interaction with ZMYND8 and RBBP4/7, represses RAD51 expression, and impairs homologous-recombination repair, leading to reduced RAD51 foci and increased γH2AX and 53BP1 accumulation. Functionally, CH41 disables CHD4-dependent DNA repair and transcriptional control, re-sensitizing temozolomide-resistant glioblastoma cells. The data establishes CH41 as the first selective CHD4 inhibitor and illustrates how advances in cellular biophysics and cellular target engagement profiling are transforming the discovery of small molecule modulators of challenging transcription factor targets, such as chromatin remodelers.", "source_company": "Emory University", "source_org_type": "大学", "row_number": 220, "target_meta": "CHD4", "MOA_meta": "抑制剂"}, {"drug_name": "STING agonist", "company": "McGill University", "org_type": "大学", "target": "STING", "modality": "other", "importance_level": "中", "total_score": 57.5, "institution_score": 30, "track_score": 85, "milestone_score": 75, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "STING激动剂针对STING通路激活IFN-I信号，与decitabine联合在转移性TNBC模型中显示显著体内协同抗瘤效果并依赖NK细胞和TBK1/IFNβ机制。机构为大学得分较低，但STING激动剂赛道热度高、转移性TNBC未满足需求强、preclinical展示清晰生存改善获较高赛道与里程碑分。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1395", "id": "glXM_5wBX1NQZOEH-LG5", "source_drug_name": "STING agonist", "title": "Combining DNA methylation inhibition and STING agonist in the treatment of metastatic triple-negative breast cancer", "abstract_text": "Triple negative breast cancer (TNBC) is an aggressive cancer associated with early metastatic events leading to a poor prognosis. According to the American Cancer Society, the 5-year relative survival rate is 91% in patients with localized TNBC but only 12% for those with distant metastatic TNBC. Thus, there is an urgent need to understand the mechanisms that drive TNBC metastasis to uncover more effective therapeutic approaches. In this regard, we profiled RNA Seq and DNA methylation in 8 metastatic TNBC cell lines with lung, liver, and bone organotropism compared to 3 parental TNBC lines. RNA-Seq revealed downregulation of IFN-I pathways associated with metastatic organotropism in the lung, liver and bone. Surprisingly, DNA methylation is enriched within the promoters of STING/IFN-related genes in these metastatic TNBC cells. In line with these findings, the analysis of TCGA human TNBC tumors showed a decreased expression of STING, an IFN-I pathway activator, in metastases versus primary tumors. In addition, a low STING expression associates with poorer TNBC patient survival. Consistent with transcriptomic data, the treatment with decitabine, a DNA methylation inhibitor, restored IFNβ and STING expression in metastatic TNBC cells, supporting epigenetic silencing with decitabine. Furthermore, combining decitabine with a STING agonist synergistically reduced viability in metastatic TNBC lines, indicating that targeting DNA methylation and activating the IFN-I pathway may represent therapeutic vulnerabilities in metastatic TNBC. More importantly, the decitabine/STINGa therapy showed a potent effect in targeting TNBC metastatic lesions in vivo with lung and liver organotropisms and increased the median survival of mice by almost 50% compared to the control single drug-treatment groups. Mechanistically, the inhibition of IFNβ with specific blocking anti-IFNβ mAb and the knockdown of TBK1, a mediator of IFN-I pathway, both abrogate the synergy between decitabine and STINGa in targeting metastatic tumor xenografts suggesting that the decitabine/STINGa targets metastatic TNBC via TBK1/IFNβ pathway. Furthermore, the spectral flow cytometry profiling of metastatic TNBC xenografts revealed that decitabine/STINGa therapy significantly enhanced NK cell infiltration and activation within metastatic tumors. Finally, the in vivo NK cell depletion showed that decitabine STINGa therapy is dependent on NK cells in treating metastatic TNBC. Altogether, this work suggests that the DNA methylation inhibition with decitabine and the stimulation of the IFNβ pathway with STINGa represent a new approach to efficiently target the metastatic TNBC that currently lacks effective targeted therapies and immunotherapies. This study also brought new evidences that decitabine/STINGa combination therapy is dependent on the TBK1/IFNβ pathway and NK cells in targeting metastatic TNBC in vivo.", "source_company": "McGill University", "source_org_type": "大学", "row_number": 397, "target_meta": "STING", "MOA_meta": "其他"}, {"drug_name": "anti-CD47 agent", "company": "Mass General Brigham Cancer Institute", "org_type": "医院", "target": "CD47", "modality": "bispecific antibody", "importance_level": "中", "total_score": 57.5, "institution_score": 35, "track_score": 85, "milestone_score": 70, "field_heat_score": 75, "bonus_score": 3, "brief_reason": "药物为优化anti-CD47臂的双特异性抗体，靶点CD47，旨在解决anti-CD47剂的血液毒性，已在临床概念验证研究中显示效果。机构为医院类型得分较低，但热门CD47+双抗赛道、临床阶段概念验证及解决关键毒性问题带来较高赛道与里程碑分。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/12143", "id": "_FXM_5wBX1NQZOEH-LK6", "source_drug_name": "anti-CD47 agent", "title": "Resolved hematological toxicities associated with anti-CD47 agents using a bispecific design involving an optimized anti-CD47 arm: A clinical proof of concept study", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Mass General Brigham Cancer Institute", "source_org_type": "医院", "row_number": 652, "target_meta": "CD47", "MOA_meta": "双特异性抗体"}, {"drug_name": "a new non-IMiD degrader", "company": "Cancer Science Institute of Singapore", "org_type": "研究机构", "target": "SALL4", "modality": "degrader", "importance_level": "中", "total_score": 57.5, "institution_score": 25, "track_score": 85, "milestone_score": 75, "field_heat_score": 70, "bonus_score": 4, "brief_reason": "靶向SALL4（包括SALL4A和SALL4B异构体）的非IMiD新型降解剂，克服IMiDs仅降解SALL4A的局限，显示体外及体内70%抑瘤活性。机构为研究机构得分较低，但PROTAC类降解剂+肿瘤关键转录因子靶点赛道热度高，前临床数据较扎实。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6469", "id": "klXM_5wBX1NQZOEH-LO6", "source_drug_name": "a new non-IMiD degrader", "title": "Identification of a small molecule degrader targeting SALL4 oncogene", "abstract_text": "Recent studies have shown that immunomodulatory imide drugs (IMiDs) could degrade SALL4 through a proteasome-dependent mechanism. Intriguingly, we found that IMiDs do not affect SALL4-positive cancer cell survival. Further studies revealed IMiDs could only degrade SALL4A, one of the SALL4 isoforms. This suggests that SALL4B, the isoform not affected by IMiDs, might be essential or compensating SALL4A in supporting cancer cell survival. Indeed, knocking downSALL4B increased apoptosis and inhibited cancer cell growth, similar to knocking down bothSALL4A and B. Moreover, SALL4B gain-of-function alone led to liver tumor formation in mice. Through high-throughput screening, we discovered a new non-IMiD degrader that targetsSALL4A and SALL4B via proteasomal degradation, showing potent anti-cancer activity by inhibiting cancer cell proliferation in culture and in vivo tumor growth by 70%. Gene expression profiling via RNA-sequencing identified a shared drug and SALL4B knock down gene signature in hepatocellular carcinoma (HCC) cells, including pathways involved in DNA damage response and DNA replication. Our findings highlight the importance of understanding drug action and oncogenesis at the isoform level to develop more effective cancer therapeutics.", "source_company": "Cancer Science Institute of Singapore", "source_org_type": "研究机构", "row_number": 747, "target_meta": "SALL4", "MOA_meta": "降解剂"}, {"drug_name": "CAR-T cell therapy", "company": "Precision for Medicine", "org_type": "公司", "target": "未披露", "modality": "CAR", "importance_level": "中", "total_score": 57.5, "institution_score": 45, "track_score": 90, "milestone_score": 40, "field_heat_score": 85, "bonus_score": 0, "brief_reason": "CAR-T细胞疗法针对血液肿瘤的持久性和免疫表型监测方法开发，未披露具体靶点或药物产品。Precision for Medicine作为专业CRO而非药企研发机构，得分中等；赛道热门但仅为监测工具开发，里程碑价值有限。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9387", "id": "mFXM_5wBX1NQZOEH-LO6", "source_drug_name": "CAR-T cell therapy", "title": "Flow cytometry-based monitoring of CAR-T cell persistence and immune phenotypes pre- and post-infusion: Challenges in Phase 1/2 hematologic malignancy trials", "abstract_text": "Chimeric antigen receptor T-cell (CAR-T) therapies that support hematological malignancies have recently had their treatment efficacy determined by both clinical outcomes and specific assessments of the CAR-T cells themselves. Assay validation typically uses control CAR-T cells spiked into healthy PBMCs, which do not fully replicate the phenotypic and scatter characteristics of patient-derived CAR-T cells after infusion. This discrepancy introduces challenges in gating accuracy and data interpretation.\nPrecision for Medicine (PfM) developed and validated a multiparameter flow cytometry assay to quantify CAR-T persistence and characterize immune phenotypes, including CD4, CD8 subsets, memory, effector differentiation, and activation/exhaustion markers. In the development and validation control CAR-T cells were used to establish the gating strategy.\nPost-infusion CAR-positive cells exhibited altered scatter profiles and marker expression compared to validation controls. Inter-assay controls ensured baseline reproducibility, but adaptive gating strategies were required for accurate identification of CAR-T populations in patient samples. These adjustments enabled robust persistence tracking and immune profiling. Clinical sample analysis was performed on peripheral blood mononuclear cells (PBMCs) pre- and post-infusion. Differences between validation controls and post-infusion CAR-T cells underscore the need for dynamic and flexible gating strategies. Addressing these challenges is critical for reliable immune monitoring in oncology trials and for correlating CAR-T persistence with clinical outcomes.", "source_company": "Precision for Medicine", "source_org_type": "公司", "row_number": 750, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "a set of potential binders for FBXW7", "company": "Massachusetts Institute of Technology", "org_type": "大学", "target": "FBXW7", "modality": "other", "importance_level": "中", "total_score": 57.5, "institution_score": 35, "track_score": 85, "milestone_score": 55, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "发现针对E3连接酶FBXW7的新型小分子结合物，可作为PROTAC新型warhead扩展TPD工具箱，属于热门靶点降解领域。机构为顶尖大学但非商业药企、仍处早期筛选+初步亲和力验证阶段导致总分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6448", "id": "CFXM_5wBX1NQZOEH-LS6", "source_drug_name": "a set of potential binders for FBXW7", "title": "Development of FBXW7 binders for targeted protein degradation", "abstract_text": "Protein-protein interactions (PPIs) play essential roles in almost all the physiological processes in human cells. Inducing or enhancing the proximity of specific PPIs for targeted protein degradation (TPD) has received much attention. TPD caused by induced protein proximity is usually achieved by two categories of small molecules: molecular glues and proteolysis targeting chimeras (PROTACs). Both categories utilize the ubiquitin-mediated proteolysis system for degradation, in which E3 ligases play vital roles in substrate recognition. Despite the fact that there are over 600 E3 ligases in the human system, only less than 10% are investigated for TPD. Here we report the discovery of a set of potential binders for FBXW7, an E3 ligase and key tumor suppressor for which no previous binders have been found. Our project aims to discover potent small-molecule binders to FBXW7, which can be used as new warheads for PROTAC design for TPD and eventually suppression of various cancers. Taking advantage of our high-throughput screening technology, Small Molecule Microarrays (SMMs), we successfully identified 3 groups of compounds (44 total) that potentially bind to FBXW7 after screening our 65,000 ‘drug-like’ small molecule library. This is done by printing these small molecules directly onto glass chips and incubating with in-house purified His-tag FBXW7, and then recognizing with fluorescence-conjugated antibody. We then performed secondary assays using nanoDSF, in which multiple small molecules from one of the groups induced over 0.3 ℃ change in the melting point of FBXW7, indicating binding activity. Interestingly, these small molecules share very similar chemical structures, which differ from others by merely one functional group on one of the 6-membered rings. Following thermo shift assay indicates that these small molecule candidates stabilize FBXW7 in a dose-dependent manner shown by western blot. So far, our leading compound is shown to have a binding affinity of 0.3μM to FBXW7 using ITC. Attempts to synthesize and test these binders for a set of proof-of-concept PROTACs are in progress. In summary, our findings identify a new set of potential binders to FBXW7, which expands the toolbox for PROTAC design. We also prove the strength of SMM as a viable methodology for the exploration of more E3 ligase binders, which will greatly benefit the development of tools in TPD for cancer therapeutics.", "source_company": "Massachusetts Institute of Technology", "source_org_type": "大学", "row_number": 836, "target_meta": "FBXW7", "MOA_meta": "其他"}, {"drug_name": "TIL-NPs", "company": "University of Texas Southwestern Medical Center", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "中", "total_score": 57.5, "institution_score": 40, "track_score": 75, "milestone_score": 70, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "TIL-NPs为多功能纳米颗粒，通过anti-CD3、anti-4-1BB和IL-2在体直接激活和重编程肿瘤浸润淋巴细胞（TILs），实现固体瘤原位T细胞疗法。机构为大学非商业化，赛道为创新纳米递送+体外T细胞激活绕过制造难题具一定新颖性，处于强preclinical阶段显示双侧瘤模型显著疗效。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9590", "id": "UlXM_5wBX1NQZOEH-LS6", "source_drug_name": "TIL-NPs", "title": "Direct in vivo activation and functional reprogramming of human TILs using a multifunctional nanoengager in humanized renal carcinoma", "abstract_text": "INTRODUCTION: Tumor-infiltrating lymphocytes (TILs) therapy has demonstrated remarkable clinical success in melanoma. However, its application in other cancers has been limited by high manufacturing cost and toxic conditioning regimen. To overcome these limitations, we aimed to develop a novel strategy to directly activate and expand TILs in vivo using a multifunctional nanoengager (TIL-NPs). In this study, we report the validation of TIL-NPs using mouse models of cancer, including a humanized renal carcinoma model that closely recapitulates human immune-tumor interactions.\nMETHODS: TIL-NPs were generated by conjugating azide-functionalized PEG-PLGA nanoparticles with DBCO-modified anti-CD3, anti-4-1BB, and IL-2. Their ability to activate and expand TILs was assessed using both MC38 and 786-O models. For the MC38 study, mice bearing bilateral tumors received intratumoral TIL-NPs in the right flank tumor only, and TIL activation was further evaluated using isolated MC38 TILs co-cultured with MC38 cells in vitro. To assess human relevance, TIL-NP-mediated expansion of human TILs was tested using renal cell carcinoma (RCC) patient samples, and a humanized RCC model was established by inoculating 786-O cells into NSG mice engrafted with human PBMCs.\nRESULTS: We engineered multifunctional nanoparticles (TIL-NPs) displaying anti-CD3, anti-4-1BB, and IL-2, measuring ~126 nm with ~50 μg of immune agonists conjugated per mg NP. In vitro, MC38 tumor-derived TILs stimulated with TIL-NPs showed markedly enhanced cytotoxicity against MC38 cells and produced the highest IFN-γ levels compared with free antibodies or unstimulated TILs. In vivo, intratumoral delivery of TIL-NPs in a bilateral MC38 model induced complete regression of all injected tumors and generated a strong systemic response, with substantial regression of contralateral tumors and improved survival. Using RCC patient-derived TILs, TIL-NPs also enhanced cytotoxicity against 786-O and ACHN cells relative to free antibodies. In a humanized RCC model, TIL-NPs produced near-complete regression of treated tumors and markedly suppressed contralateral tumor growth. Immunohistochemistry confirmed dense CD8⁺ T-cell infiltration in TIL-NP-treated tumors, indicating enhanced activation and recruitment of cytotoxic T cells. Overall, TIL-NPs strengthened T-cell signaling through receptor clustering, prolonged survival, and elicited potent local and systemic antitumor responses.\nCONCLUSION: TIL-NPs potently activate and reprogram TILs in vivo, enhancing cytotoxicity and systemic antitumor immunity, highlighting their translational potential for adoptive T-cell therapy in solid tumors.", "source_company": "University of Texas Southwestern Medical Center", "source_org_type": "大学", "row_number": 889, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "Acetalax", "company": "National Cancer Institute", "org_type": "研究机构", "target": "TRPM4", "modality": "other", "importance_level": "中", "total_score": 57.5, "institution_score": 45, "track_score": 65, "milestone_score": 70, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "Acetalax通过毒化TRPM4离子通道诱导oncosis样细胞死亡，靶向TRPM4这一在难治性前列腺癌中高表达的潜在新靶点。NCI研究机构背景+preclinical PDX有效数据+新机制亮点，但非热门modality和靶点热度中等导致总分中位。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9851", "id": "MZ7M_5wBZznHJdnt_W3O", "source_drug_name": "Acetalax", "title": "TRPM4 expression predicts Acetalax sensitivity in prostate cancer", "abstract_text": "Background: Advanced and treatment-refractory prostate cancer, including castration-resistant disease, highlights the need for new therapeutic strategies exploiting targetable vulnerabilities. TRPM4, a calcium-activated monovalent cation channel, regulates cell volume and promotes cancer progression. Our research showed that Acetalax induces selective oncosis-like cell death in TRPM4-positive triple-negative breast cancer, suggesting TRPM4-dependent susceptibility. Targeting TRPM4 may offer advantages over existing therapies by disrupting ion-transport and volume-regulatory mechanisms not addressed by current treatments. We examined TRPM4 expression and Acetalax activity in prostate cancer.\nMethods: We assessed Acetalax sensitivity in prostate cancer cell lines with high or low TRPM4, including androgen-dependent (LNCaP) and castration-resistant models (PC3, DU145, 22Rv1). TRPM4 dynamics, cellular swelling, and oncosis-associated phenotypes were evaluated by Western blotting and immunofluorescence. Resistant clones were developed by continuous drug exposure. TRPM4 expression in patient samples was analyzed using tissue microarrays (TMAs) and TCGA. Transcriptomic changes following TRPM4 loss were examined by RNA sequencing. Antitumor activity and tolerability were tested in TRPM4-positive PDX models.\nResults: TRPM4-high prostate cancer cells exhibited rapid swelling, membrane blebbing, and TRPM4 degradation after Acetalax, whereas TRPM4-low cells and resistant clones lacking TRPM4 were unaffected. Resistant clones showed TRPM4 depletion, confirming TRPM4 is required for responsiveness. In patient samples, TRPM4 protein was higher in adenocarcinoma than benign hyperplasia, and TCGA datasets confirmed increased TRPM4 transcripts in tumors relative to normal tissue, with minimal differences across stage or Gleason grade. Transcriptomic profiling revealed gene-expression changes associated with TRPM4 loss, including alterations in ion transport, cytoskeletal organization, and cell-death-related pathways, with a shift toward proliferative programs and reduced stress and inflammatory signaling consistent with disrupted volume-regulatory networks. In vivo, Acetalax significantly suppressed growth of TRPM4-positive PDX tumors in a dose-dependent manner without systemic toxicity.\nConclusions: TRPM4 functions as a target and predictive biomarker for Acetalax response in prostate cancer. These findings highlight a TRPM4-dependent therapeutic vulnerability and support biomarker-guided development of Acetalax for TRPM4-expressing, treatment-refractory prostate cancer, including CRPC.", "source_company": "National Cancer Institute", "source_org_type": "研究机构", "row_number": 981, "target_meta": "TRPM4", "MOA_meta": "其他"}, {"drug_name": "BCMAxCD3 BiTE", "company": "Beckman Research Institute of City of Hope", "org_type": "研究机构", "target": "BCMA", "modality": "bispecific antibody", "importance_level": "中", "total_score": 57.5, "institution_score": 35, "track_score": 85, "milestone_score": 55, "field_heat_score": 75, "bonus_score": 3, "brief_reason": "BCMAxCD3 BiTE为靶向BCMA的双特异性T细胞衔接器，结合健康供体多病毒特异性记忆T细胞（mVSTs）实现off-the-shelf异体应用，增强亚优T细胞应答患者的疗效。研究机构背景限制机构分，但热门TCE模态+BCMA靶点+创新非工程化异体平台有较强赛道热度和一定转化潜力。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4547", "id": "YZ7M_5wBZznHJdnt_W3O", "source_drug_name": "BCMAxCD3 BiTE", "title": "Leveraging off-the-shelf T cells to enhance bispecific T cell engager therapy efficacy in patients with suboptimal T cell responses", "abstract_text": "Bispecific T cell engagers (BiTEs) have showed potent antitumor activity in hematologic malignancies but are often limited by T-cell dysfunction in patients. To overcome this challenge, we developed an off-the-shelf immunotherapy platform using healthy donor-derived multi-virus-specific T cells (mVSTs) as effectors for BiTE-mediated redirection. These memory-derived mVSTs recognize cytomegalovirus (CMV) and Epstein-Barr virus (EBV) antigens, exhibit central and effector memory phenotypes, and carry minimal graft-versus-host disease (GVHD) risk, providing a bankable, and functional T-cell source.mVSTs were expanded from CMV/EBV-seropositive donors and evaluated in multiple myeloma and lymphoma models. Two BiTE-loading strategies were tested: pre-incubation with T cells (armored) or direct addition to co-culture. mVSTs alone exhibited minimal cytotoxicity, whereas BCMAxCD3 BiTE-redirected mVSTs mediated robust tumor lysis in both approaches (89.8 ± 1.7% and 88.7 ± 0.4%, respectively at 72h and E:T 1:4) and expanded ≥3-fold versus no-BiTE controls. Both loading methods triggered robust activation, with marked upregulation of CD137 and CD25 and substantial increases in effector cytokines. In Raji lymphoma models, CD19×CD3 and CD20×CD3 BiTEs produced 48-52% cytotoxicity with armored mVSTs, and direct BiTE addition further enhanced killing to 73-74% with a comparable activation profile. Collectively, BiTE-redirected mVSTs exhibit potent cytotoxicity, robust activation, and strong effector cytokine release across myeloma and lymphoma targets, validating their function as an effective, off-the-shelf T-cell platform. A single donor-derived mVST source can be paired with multiple BiTEs to address tumor heterogeneity or antigen-loss relapse without engineering. These data support the feasibility and translational promise of combining BiTEs with healthy donor-derived mVSTs to generate scalable, non-engineered allogeneic T-cell immunotherapies for diverse malignancies.", "source_company": "Beckman Research Institute of City of Hope", "source_org_type": "研究机构", "row_number": 1015, "target_meta": "BCMA", "MOA_meta": "双特异性抗体"}, {"drug_name": "JZY-2233", "company": "University of Michigan", "org_type": "大学", "target": "CBP/p300", "modality": "other", "importance_level": "中", "total_score": 57.5, "institution_score": 35, "track_score": 75, "milestone_score": 75, "field_heat_score": 70, "bonus_score": 5, "brief_reason": "JZY-2233为PSMA靶向的CBP/p300 degrader-antibody conjugate（DAC），通过抗体偶联实现肿瘤特异性降解CBP/p300，显著提升前列腺癌模型疗效并降低毒性。大学机构得分较低，但degrader+ADC-like创新机制结合强效preclinical数据（单剂持久抑瘤+低毒）使赛道与里程碑热度较高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5668", "id": "tJ7M_5wBZznHJdnt_W3O", "source_drug_name": "JZY-2233", "title": "JZY-2233: An antigen-targeted CBP/p300 degrader-antibody conjugate for advanced prostate cancer therapy", "abstract_text": "Background: CBP/p300 are essential transcriptional coactivators of the androgen receptor and play a critical role in prostate cancer pathogenesis. Small-molecule CBP/p300 degraders have demonstrated potent efficacy against prostate cancer but are limited by toxicity, impeding clinical translation.\nMethods:To enhance tumor specificity and minimize systemic toxicity, we developed a Degrader-Antibody Conjugate (DAC) by linking a highly potent CBP/p300 degrader to a prostate-specific membrane antigen (PSMA) antibody, generating JZY-2233. In vitro antiproliferative activities were assessed using VCaP and LNCaP prostate cancer cell lines. In vivo efficacy, pharmacodynamics, and toxicity were evaluated in a LNCaP xenograft mouse model.\nResults: JZY-2233 induced robust growth inhibition in VCaP and LNCaP cells, with picomolar IC50 values. In vivo, treatment with JZY-2233 led to sustained CBP/p300 degradation and suppression of c-Myc and PSA in tumor tissues, with effects persisting up to 168 hours post-dose. A single administration at 10 mg/kg resulted in complete tumor suppression for over 90 days in the LNCaP model, significantly exceeding the effect of the unconjugated parent degrader. Importantly, JZY-2233 markedly reduced systemic toxicity.\nConclusions: JZY-2233 is a highly potent, antigen-targeted CBP/p300-PSMA DAC, offering prolonged tumor suppression and reduced toxicity in models of advanced prostate cancer. This approach provides a strong rationale for further evaluation in clinical studies and may be adapted for targeting additional tumor antigens across diverse cancers.", "source_company": "University of Michigan", "source_org_type": "大学", "row_number": 1077, "target_meta": "CBP/EP300", "MOA_meta": "其他"}, {"drug_name": "A101-AB-MMAE", "company": "National Cancer Institute, National Institutes of Health", "org_type": "研究机构", "target": "MSLN", "modality": "nanobody-drug conjugate", "importance_level": "中", "total_score": 57.5, "institution_score": 45, "track_score": 75, "milestone_score": 55, "field_heat_score": 65, "bonus_score": 3, "brief_reason": "药物为靶向MSLN的nanobody-drug conjugate（A101-AB-MMAE），利用新型linker实现细胞内特异切割，体外IC50 20-200 nM，体内小鼠模型显示显著肿瘤抑制且特异性高。机构为NCI政府研究单位非商业头部公司得分中等，ADC类热门赛道+胰腺癌未满足需求但仍处preclinical早期且非突破性新机制，总分中等水平。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9651", "id": "lJ7M_5wBZznHJdnt_W7P", "source_drug_name": "A101-AB-MMAE", "title": "Mesothelin-targeted nanobody-drug conjugates to treat pancreatic cancer", "abstract_text": "Development of targeted therapies that can penetrate the dense stroma of the pancreatic ductal adenocarcinoma (PDAC) tumor microenvironment (TME) is essential to improve outcomes for pancreatic cancer patients. We have discovered a camel VHH nanobody (A101) using phage display, which effectively binds to mesothelin (MSLN), a cancer antigen that is expressed in PDAC. Using the A101 VHH nanobody with an MMAE payload, we generated nanobody-drug conjugates (NDCs) that can be advantageous compared to existing biologic therapies by enhancing tumor penetration through the PDAC TME and improving pharmacokinetic distribution, while minimizing systemic toxicity.\nThe structure of the A101 nanobody was computationally predicted and molecular dynamic simulations were run to understand its interaction with MSLN. Site-specific modifications were engineered and small linker-MMAE molecules were synthesized, then bioconjugated to the modified A101 nanobody using maleimide chemistry. The chemical linkers used in these constructs were valine-citrulline, glycine-proline, and AB (a novel small molecule). The NDCs were tested for binding to MSLN via bio-layer interferometry assays. Internalization and cell viability were also assessed using mouse and human PDAC cell lines. Finally, in vivo activity was assayed in MSLN+ and MSLN knockout (MLSN-KO) subcutaneous mouse PDAC tumor models to determine efficacy and specificity of each therapeutic.\nWe found that modified A101 nanobody retains binding to human (KD = 18 nM) and mouse (KD = 5.6 nM) MSLN. A101 NDCs displayed a statistically significant difference in internalization into MSLN+ as compared to isogenic MSLN-KO cells. Additionally, the NDCs efficiently killed PDAC cell lines in vitro (IC50 = 20-200 nanomolar). In mice, the A101-AB-MMAE NDC (at 20 mg/kg, 3x per week) displayed the most promising inhibition of tumor growth in MSLN+ tumors and had the highest specificity compared to other A101-NDCs tested, showing limited efficacy in analogous MSLN-KO tumors.\nWe have synthesized A101-based NDCs with high-affinity MSLN binding and promising anti-tumor activity in PDAC cell lines. Our preliminary animal studies suggest that the A101-AB-MMAE conjugate, which has a novel exclusively intracellular cleavable linker, has superior efficacy and specificity compared to other A101-based NDCs tested with known linkers. Future studies will explore A101-AB-MMAE activity in orthotopic humanized MSLN mouse models of PDAC to assess safety, biodistribution, and anti-tumor efficacy.", "source_company": "National Cancer Institute, National Institutes of Health", "source_org_type": "研究机构", "row_number": 1225, "target_meta": "MSLN", "MOA_meta": "抗体偶联药物"}, {"drug_name": "CART87", "company": "Thomas Jefferson University", "org_type": "大学", "target": "CD87", "modality": "CAR", "importance_level": "中", "total_score": 57, "institution_score": 35, "track_score": 85, "milestone_score": 55, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "CART87针对CD87（uPAR）开发CAR-T疗法，用于结直肠癌，靶点在CRC中近乎普遍高表达且正常组织表达有限，具有较好安全性基础。大学机构得分较低，但CAR赛道及实体瘤热门靶点热度高，处于体外优化到即将推进体内验证的早期临床前阶段，整体重要性中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9380", "id": "SVXM_5wBX1NQZOEH-LG5", "source_drug_name": "CART87", "title": "Preclinical development and evaluation of CD87-directed CART for colorectal cancer", "abstract_text": "Background: Chimeric antigen receptor T-cell (CAR-T) therapy has shown success in hematologic malignancies; however, its efficacy in solid tumors, including colorectal cancer (CRC), remains limited by poor tumor penetration, an immunosuppressive microenvironment, antigen heterogeneity, and a risk of on-target/off-tumor toxicities. CD87, the receptor for the urokinase plasminogen activator (uPAR), has emerged as a promising target, given its near-universal overexpression in CRC, and its near absence in normal tissues, except certain myeloid cells. Recent studies on the elimination of senescent myeloid cells in mice have supported the safety of CD87-directed CAR-T cells in vivo. Here, we pursued safety and efficacy studies of human CD87-directed CART (CART87) for use in CRC. We employed a Jurkat NFAT-Lucia reporter platform to functionally screen and optimize human CD87-specific CAR designs, then advanced the top candidates into CARTs for testing against a panel of CRC cell lines. Moreover, we employed bioinformatics to identify potential risks associated with targeting CD87 in humans.\nMethods: To assess the potential safety of targeting CD87, we analyzed public bulk and scRNAseq datasets from human and mouse tissues. Furthermore, we quantified CD87 surface expression in human blood leukocyte populations and assessed their susceptibility to CART87. To optimize the CAR87 design, we employed a Jurkat NFAT-Lucia reporter assay, which measured CAR activation upon stimulation with recombinant uPAR and CD87-expressing cells. Constructs with high tonic signaling and non-specific activation by CD87-negative cells were eliminated. We then engineered CD87-directed CAR-T cells (CART87) and assessed their activity against CD87-positive CRC cell lines compared with CD87-negative HEK293 cells and CD87 knockout (KO) cells.\nResults: scRNAseq analysis of bone marrow, whole blood leukocytes, and organ tissues revealed that CD87 mRNA expression is restricted to mature monocyte-lineage cells, with murine organs/tissues showing analogous results. Correspondingly, CD87 surface expression by flow cytometry was largely restricted to mature myeloid lineage cells. The Jurkat-NFAT reporter system enabled rapid comparison of single-chain variable fragments (scFv), structural and signaling domain configurations, and identified lead construct #3 (CAR87.3). CART87.3 demonstrated specific and potent cytolytic activity in vitro against CD87-positive CRC cell lines T84, SW480, LS174T, and DLD1.\nConclusions: This work identifies CD87 as a safe, selectively-expressed target antigen for the development of CAR-T therapy in CRC. The in vitro results support the advancement of human CART87 towards in vivo validation. Furthermore, we describe the rational design of a CART87 construct using a high-throughput strategy that could be broadly applied in CAR design for other target antigens.", "source_company": "Thomas Jefferson University", "source_org_type": "大学", "row_number": 360, "target_meta": "PLAUR", "MOA_meta": "其他"}, {"drug_name": "antibodies directed against cytokines enriched in the CSF", "company": "University of Cambridge", "org_type": "大学", "target": "未披露", "modality": "inhibitor", "importance_level": "中", "total_score": 57, "institution_score": 35, "track_score": 65, "milestone_score": 75, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "使用针对脑脊液中富集细胞因子的抗体（靶点未明确披露）阻断髓系偏向和Treg极化，实现多种儿童恶性脑瘤模型的显著肿瘤消退；大学机构得分较低，但preclinical中展示清晰肿瘤回归的里程碑价值及潜在低毒性新策略使其具有一定吸引力。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4810", "id": "4FXM_5wBX1NQZOEH-LG6", "source_drug_name": "antibodies directed against cytokines enriched in the CSF", "title": "Reversing brain tumor immunotolerance: A new therapeutic approach for childhood brain tumors", "abstract_text": "Brain tumours kill more children than any other cancer. Although immunotherapies have proved effective against treatment-resistant adult cancers and some leukamias, they have proved less effective against brain tumours. This is due in part to a poor understanding of how the immune system operates within the central nervous system (CNS), hindered further by a long-held belief that the brain is an immunoprivileged site, devoid of immune activity. Recent research challenges this view, revealing active immunosurveillance within the CNS. Using a novel genetically engineered mouse model of ZFTA-RELA ependymoma-a childhood brain tumour-we characterised an immune circuit between the tumour and antigen presenting, haematopoietic stem/progenitor cells (HSPCs) in the skull bone marrow. The presentation of antigens by HSPCs to CD4+ T cells, biased HSPC lineages toward myelopoiesis and polarised CD4+ T-cells to regulatory T cells (T-regs), culminating in tumour immunotolerance. Remarkably, normalising haematopoiesis with a single infusion of antibodies directed against cytokines enriched in the CSF of mice bearing ZFTA-RELA ependymomas, choroid plexus carcinomas or Group-3 medulloblastoma-all aggressive childhood brain tumours-disrupted this process and caused profound tumour regression. These findings uncover a skull bone marrow-tumour immunological interface and suggest that modulating local supply of myeloid cells may offer a less-toxic therapeutic strategy for aggressive childhood brain tumours.", "source_company": "University of Cambridge", "source_org_type": "大学", "row_number": 465, "target_meta": "not available", "MOA_meta": "抑制剂"}, {"drug_name": "RB-322", "company": "University of Michigan", "org_type": "大学", "target": "PRC1 (Ring1A/B)", "modality": "inhibitor", "importance_level": "中", "total_score": 57, "institution_score": 40, "track_score": 65, "milestone_score": 75, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "RB-322为靶向PRC1 (Ring1A/B) E3连接酶活性的新一代小分子抑制剂，作为化学探针显示低纳摩尔生化活性及AML细胞系中快速去泛素化和基因去抑制效应。机构为大学得分一般，赛道为表观遗传新兴但非最热门靶点，preclinical数据扎实具优化亮点，总分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6525", "id": "ZVXM_5wBX1NQZOEH-LK6", "source_drug_name": "RB-322", "title": "Evaluation of novel small molecule inhibitors targeting Polycomb repressive complex 1 as chemical probes", "abstract_text": "Background: Polycomb Repressive Complex 1 (PRC1) is an epigenetic regulatory complex responsible for monoubiquitylation of lysine 119 on histone H2A (H2AK119Ub). This ubiquitylation activity is mediated by a canonical heterodimeric E3 ligase involving Ring1B (or its paralog Ring1A) bound to BMI1. Deposition of H2AK119Ub is associated with gene repression at loci involved in determining cell fate and identity. Notably, genetic depletion of Ring1A and Ring1B results in reduction of H2AK119Ub, derepression of PRC1 target genes, and cell growth arrest in a leukemia model. Therefore, small molecules targeting the ubiquitylation activity of Ring1A/B are useful chemical probes towards studying PRC1 biology.\nResults: We have previously developed RB-3: a first in class small molecule inhibitor of PRC1. Here we report the next generation of novel small molecule PRC1 inhibitors. Employing structure-based design, we have developed a potent cell permeable next generation inhibitor RB-322. RB-322 is a mixture of two atropisomers which were separated yielding RB-322-1 and RB-322-2. To validate direct binding of our inhibitors to Ring1A/B we used 2D HSQC. Notably, RB-322-1 demonstrates slow exchange while RB-322-2 demonstrates fast exchange indicating strong and weak binding respectively. We then used an AlphaScreen competition assay to evaluate RB-322-1 mediated disruption of the PRC1-nucleosome interaction in vitro in which it shows low nanomolar activity. A novel radiometric ubiquitylation activity assay (RadUb) was then developed to quantitatively assess inhibition of PRC1 E3 ligase activity. Using this assay we found RB-322-1 demonstrates sub-micromolar activity. RB-322-2 is 2 orders of magnitude weaker in these assays. We then investigated the on-target activity of RB-322 in leukemia cell lines. First, we developed a biotinylated RB-322 probe and performed streptavidin-based pull downs followed by proteomics analysis revealing enrichment of multiple PRC1 proteins. We then evaluated the effects of RB-322-1 on cellular H2AK119Ub and gene expression. We found RB-322-1 demonstrates rapid and dose-dependent reduction of the H2AK119Ub mark after 6-hours and derepresses PRC1 target genes in AML cell lines. Crucially, these effects have not been observed for the weak atropisomer RB-322-2.\nConclusions: Extensive medicinal chemistry optimization has yielded a potent cell permeable next generation small molecule inhibitor of PRC1: RB-322. RB-322 demonstrates low nanomolar activity in biochemical assays in vitro and demonstrates on-target derepression of PRC1 genes providing novel mechanistic insights. RB-322 represents a useful chemical probe for studying PRC1 biology and serves as the foundation for a potential novel anti-cancer agent.", "source_company": "University of Michigan", "source_org_type": "大学", "row_number": 550, "target_meta": "PRC1", "MOA_meta": "抑制剂"}, {"drug_name": "off-the-shelf NK cell therapies", "company": "UT MD Anderson Cancer Center", "org_type": "医院", "target": "未披露", "modality": "CAR", "importance_level": "中", "total_score": 57, "institution_score": 45, "track_score": 85, "milestone_score": 40, "field_heat_score": 80, "bonus_score": 0, "brief_reason": "off-the-shelf NK细胞疗法（主要为CAR-NK）属于细胞治疗热门赛道，靶点和具体机制未披露。MD Anderson作为顶级肿瘤医院在NK/CAR-NK领域有较强积累，但非商业公司且无具体里程碑数据，得分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/2303", "id": "UJ7ECZ0BZznHJdntvNYd", "source_drug_name": "off-the-shelf NK cell therapies", "title": "Off-the-shelf NK cell therapies from biology to the clinic", "abstract_text": "There is no abstract associated with this presentation.", "source_company": "UT MD Anderson Cancer Center", "source_org_type": "医院", "row_number": 594, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "lipid polymer vaccine carrying FITC", "company": "Children's Hospital of Philadelphia", "org_type": "医院", "target": "未披露", "modality": "vaccine", "importance_level": "中", "total_score": 57, "institution_score": 35, "track_score": 75, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 6, "brief_reason": "该脂质聚合物疫苗携带FITC用于刺激旁观者CAR-T，意外触发抗原非依赖的肿瘤消退机制，涉及IFNγ和TME重塑。机构为医院得分较低，但新颖旁观者效应机制+小鼠模型显著疗效及与PD-L1联合潜力带来较高中价值。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3630", "id": "qlXM_5wBX1NQZOEH-LK6", "source_drug_name": "lipid polymer vaccine carrying FITC", "title": "Vaccine stimulation of bystander t cells in the lymph node unexpectedly promotes tumor-specific host immunity to regress solid tumors", "abstract_text": "Personalized neoantigen cancer vaccines have been at the forefront of therapeutic vaccination. However, although these neoantigen vaccines do induce neoantigen-specific T cell responses, the clinical effects are limited. Logistical challenges, such as the time required for developing personalized neoantigen vaccines, also limit their clinical utility. We were recently intrigued by a case at Penn where one of our patients had a 7.6 cm melanoma tumor and experienced a complete response after receiving the COVID-19 vaccine alone, consistent with a recent report that cancer patients who received the SARS-CoV-2 vaccination had improved survival. Further studies identified abundant SARS-CoV-specific T cells present in both the draining lymph node (LN) and in the necrotic tumor bed. At the same time, our preliminary experiment in mice showed a similar phenomenon that the activation of tumor-irrelevant CAR T cells by vaccination reinvigorated the host’s tumor-specific immunity and regressed established solid tumors. Specifically, when we used our recently developed lipid polymer vaccine (Ma et al, Science, 2019; Cell, 2023; Grzywa et al, Nat BME, 2025) carrying a chemical ligand Fluorescein (FITC) to specifically stimulate adoptively transferred bystander FITC-targeting chimeric antigen receptor (CAR) T cells in vivo in the lymph node as a negative control, yet unexpectedly we observed distal tumor regression to a level that’s comparable to vaccine stimulation of tumor-specific CAR T in syngeneic mouse models of pancreatic cancer and melanoma. In both settings, tumor volume was reduced by>70% within the first 72 hours, and this effect persisted for up to 2 weeks (with some cures of the melanoma). This marked antigen-independent tumor control is completely lost in Rag1-knockout (no endogenous T cells) and BatF3-knockout (deficient in antigen cross-presentation) recipient mice. FITC vaccine boosting of bystander FITC-CAR T induced a rapid and transient cytokine and chemokine release that distally remodels the tumor microenvironment. Notably, IFNg blockade completely abolished this tumor control. In the pancreatic cancer model, IFNg significantly upregulated PD-L1 expression in cancer cells. As a result, co-administration of anti-PD-L1 markedly extended long-term tumor control and animal survival. Collectively, these unexpected findings in both the melanoma patient and syngeneic mouse models of solid tumors suggested a previously unappreciated anti-tumor bystander effect associated with vaccine-mediated T cell activation.", "source_company": "Children's Hospital of Philadelphia", "source_org_type": "医院", "row_number": 597, "target_meta": "not available", "MOA_meta": "疫苗"}, {"drug_name": "MTA-cooperative PRMT5 inhibitors", "company": "Virginia Tech Cancer Research Center", "org_type": "研究机构", "target": "PRMT5", "modality": "inhibitor", "importance_level": "中", "total_score": 57, "institution_score": 35, "track_score": 85, "milestone_score": 55, "field_heat_score": 75, "bonus_score": 0, "brief_reason": "药物为MTA-cooperative PRMT5抑制剂，针对MTAP缺失肿瘤的合成致死机制，靶点PRMT5在精准治疗中具有较高热度。机构为大学研究中心而非商业公司导致总体分值受限，但赛道和科学深度仍有一定价值。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3028", "id": "MlXM_5wBX1NQZOEH-LO6", "source_drug_name": "MTA-cooperative PRMT5 inhibitors", "title": "Multi-omics characterization of PRMT5 inhibition identifies vulnerabilities for combination therapy in MTAP-deleted cancers", "abstract_text": "Homozygous deletion of CDKN2A on chromosome 9p21 is the most frequent genomic loss in cancer and often extends into the adjacent MTAP gene. This co-deletion occurs in ~10% of tumors (>200,000 cases annually in the U.S) and is particularly enriched in aggressive malignancies such as glioblastoma (GBM), malignant peripheral nerve sheath tumors (MPNST), pancreatic ductal adenocarcinoma (PDAC), and non-small cell lung cancer (NSCLC). In these tumors, MTAP loss leads to intracellular accumulation of its substrate methylthioadenosine (MTA), which partially inhibits protein arginine methyltransferase 5 (PRMT5) by competing with its methyl donor S-adenosyl-methionine (SAM) at the active site, reducing its ability to symmetrically dimethylate arginine residues (SDMA). This creates a synthetic-lethal dependence on residual PRMT5 activity and has driven the development of MTA-cooperative PRMT5 inhibitors, which show encouraging preclinical activity and single-agent response rates of 21-29% in early clinical trials in the advanced, refractory setting. We therefore hypothesized that defining the molecular consequences of PRMT5 inhibition could guide patient stratification and inform rational combination strategies capable of enhancing therapeutic efficacy and preventing resistance. To test this, we performed multi-omics profiling, including short- and long-read transcriptomics and whole-cell proteome mass spectrometry, across MTAP-deleted NSCLC, GBM, and PDAC models, integrating these data with in-house and publicly available datasets to define PRMT5-dependent methyl events and their downstream molecular consequences. Transcriptomic and proteomic analyses revealed strong and consistent pathway-level alterations across models following PRMT5 inhibition, including activation of MAPK signaling, a compensatory program validated to synergize with PRMT5 inhibitors in vitro and in vivo. Across eight distinct PRMT5 methyl-enrichment mass spectrometry studies, we identified 180 PRMT5 substrates enriched mainly for proteins involved in RNA metabolism and pre-mRNA splicing, including multiple snRNP-associated components of the spliceosome. We therefore examined the splicing consequences of PRMT5 inhibition and observed widespread increases in intron retention and reductions in exon skipping, with enrichment of splicing alterations in transcripts involved in DNA damage repair across models. Overall, this study provides a comprehensive substrate map of PRMT5 and characterizes the transcriptional, proteomic, and splicing programs activated upon its inhibition across MTAP-deleted GBM, NSCLC, and PDAC models. These findings highlight pathway and splicing-associated vulnerabilities as targets for rational combination strategies and establish a mechanistic framework to guide biomarker development and future therapeutic exploration.", "source_company": "Virginia Tech Cancer Research Center", "source_org_type": "研究机构", "row_number": 687, "target_meta": "PRMT5", "MOA_meta": "抑制剂"}, {"drug_name": "cyclic peptide radioligands", "company": "ICE Bioscience", "org_type": "公司", "target": "B7-H3, DLL3", "modality": "other", "importance_level": "中", "total_score": 57, "institution_score": 45, "track_score": 85, "milestone_score": 45, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "靶点为新兴RDC热门靶点B7-H3（免疫检查点）和DLL3（Notch配体），modality为cyclic peptide radioligands，结合AI加速发现平台实现preclinical验证。机构为国内CRO公司，非头部药企，开发处于早期preclinical阶段但AI平台有一定亮点。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6494", "id": "PFXM_5wBX1NQZOEH-LO6", "source_drug_name": "cyclic peptide radioligands", "title": "AI-accelerated discovery of B7-H3 and DLL3-targeted cyclic peptide radioligands: From library design to preclinical validation", "abstract_text": "Background: Radiopharmaceutical drug conjugates (RDCs) represent a transformative paradigm in precision oncology, yet target-specific ligand discovery remains a critical bottleneck. We developed an integrated AI-augmented platform to rapidly identify cyclic peptide binders for two emerging RDC targets: B7-H3 (immune checkpoint) and DLL3 (Notch ligand).\nMethods: A structurally diverse phage display library (1.5×1011capacity; 8-17 aa macrocycles) was engineered with NGS-validated complexity. Recombinant 4Ig-B7-H3 (2Ig-B7-H3 as off-target counterscreens), DLL3 (and counterscreens DLL1/DLL4) underwent orthogonal biophysical characterization by SPR and Spectral shift assay (SPS). Hit triangulation employed: (1) Deep sequencing-driven consensus motif analysis, (2) AlphaFold3 multimer modeling of peptide-target complexes, and (3) Parallel SPR/spectral shift assays (10⁻⁷ M affinity threshold). Top candidates were Cy5-labeled for real-time binding and internalization kinetics in engineered tumor lines.\nResults: Discovery: 15/40 phage clones demonstrated target binding - AI optimization: AlphaFold3 predictions revealed a conserved β-turn motif in 7/15 top hits that anchors to a cryptic pocket in targets - Validation: Hit peptide were synthesized and showed: (i) KD 8.2×10⁻7 M (SPR), (ii) >3-fold selectivity over homologous target proteins (iii) showed binding on cells\nConclusions: This platform addresses critical challenges in RDC development by providing a streamlined solution for hit discovery, optimization, and validation. The integration of AI-driven structural prediction with high-throughput experimental validation compresses traditional hit discovery timelines This platform will significantly accelerate the RDC development pipeline—especially for hit binder identification for neo tumor antigens or other validated surface proteins like GPCRs, transporters, to accelerate RDC drug discovery using cyclic peptide as the modality.", "source_company": "ICE Bioscience", "source_org_type": "公司", "row_number": 695, "target_meta": "CD276,DLL3", "MOA_meta": "其他"}, {"drug_name": "CIDD-0166596", "company": "UTHSA", "org_type": "学术机构", "target": "ERβ", "modality": "agonist", "importance_level": "中", "total_score": 57, "institution_score": 45, "track_score": 65, "milestone_score": 70, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "靶点为ERβ激动剂，具有优异脑渗透性，在体外/体内GBM模型中显示抗瘤活性并增强TMZ疗效。机构为大学学术中心（非头部药企），赛道为脑瘤靶向小分子激动剂（非最热门ADC/双抗），但有较强preclinical数据和优化亮点。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5595", "id": "O1XM_5wBX1NQZOEH-LS6", "source_drug_name": "CIDD-0166596", "title": "Next-generation ERβ agonists with superior brain uptake suppress glioblastoma and enhance temozolomide response", "abstract_text": "Background: Glioblastoma (GBM) is the most common and aggressive primary brain malignancy in adults, with a dismal 5-year overall survival rate. Epidemiologic studies suggest that estrogen receptor beta (ERβ) exerts tumor-suppressive effects in the brain, supporting its potential as a therapeutic target. However, the lack of potent, selective, and brain-penetrant ERβ ligands has hindered translational progress. We recently identified indanone- and tetralone-keto/hydroxyloxime derivatives (CIDD-0149897) as promising ERβ agonist. Here, we report the structure-guided design, synthesis, and preclinical validation of next-generation ERβ agonists with markedly improved potency, selectivity, safety, and blood-brain barrier permeability for GBM therapy.\nMethods: To optimize the CIDD-0149897 scaffold and define key pharmacophores, we designed and synthesized 177 analogues using structure-based drug design incorporating ERβ-LBD X-ray data across multiple chemotypes. ERβ versus ERα selectivity was quantified using dual-luciferase reporter assays. Cytotoxicity and apoptosis were assessed in patient-derived and mouse glioblastoma stem cells (GSCs) via CellTiter-Glo and Annexin-V assays. Mechanistic studies employed Western blotting, RT-qPCR, comet assays, RNA-seq, and mass spectrometry. In vitro ADME and PK were performed through the UTSA Center for Innovative Drug Discovery. Therapeutic efficacy of lead ERβ agonists was evaluated in orthotopic syngeneic and patient-derived xenograft GBM models.\nResults: Five optimized ERβ agonists displayed substantially improved potency and selectivity. ADME analyses demonstrated 20-50-fold higher aqueous solubility and excellent plasma stability relative to CIDD-0149897. Two analogues CIDD-0169124 and CIDD-0166596 showed ≥10-fold higher brain exposure than CIDD-0149897, with a peak brain/plasma ratio of 3.12 ± 0.84 at 15 minutes, indicating rapid brain uptake. Both lead molecules reduced human and mouse GSC viability with low-micromolar IC₅₀ values and significantly enhanced temozolomide (TMZ) response, increasing DNA damage and suppressing neurosphere formation. Comet assays revealed marked increases in olive tail moment with combination treatment compared to monotherapy. In vivo, CIDD-0169124 and CIDD-0166596 significantly reduced tumor burden and prolonged survival in orthotopic xenograft GBM models. Combination with TMZ further extended survival. Immunohistochemistry of tumor sections showed decreased Ki-67 and increased cleaved caspase-3 in combination-treated tumors.\nConclusion: Two improved ERβ agonists outperformed CIDD-0149897 in potency, selectivity, safety, and brain penetration. These compounds show strong anti-GBM action and enhance TMZ efficacy, supporting their development as next-generation ERβ-targeted therapeutics for GBM. Supported by NIH RO1 CA269866.", "source_company": "UTHSA", "source_org_type": "未知", "row_number": 874, "target_meta": "ESR2", "MOA_meta": "激动剂"}, {"drug_name": "NAMPTi", "company": "University of Alabama at Birmingham", "org_type": "大学", "target": "NAMPT", "modality": "inhibitor", "importance_level": "中", "total_score": 57, "institution_score": 35, "track_score": 75, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "新型NAMPT抑制剂通过阻断NAD合成增强PDAC标准化疗及免疫调控效果，靶点机制新颖且具协同潜力。大学机构得分较低，但赛道机制热度较高且前临床协同及免疫重塑数据清晰，支持中度重要性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3442", "id": "ZFXM_5wBX1NQZOEH-LS6", "source_drug_name": "NAMPTi", "title": "NAMPT inhibition enhances the efficacy of standard chemotherapies and immunomodulation in pancreatic ductal adenocarcinoma", "abstract_text": "Background: Pancreatic ductal adenocarcinoma (PDAC) is characterized by high metabolic demand and dependency on NAD salvage pathways. NAMPT, the rate-limiting enzyme in NAD biosynthesis, is upregulated in PDAC and supports tumor survival under therapeutic stress. We investigated the preclinical activity of a novel hyperbolic NAMPT inhibitor (NAMPTi) in combination with standard-of-care (SOC) chemotherapy regimens including gemcitabine, paclitaxel, 5-FU, oxaliplatin, hydroxychloroquine, and paricalcitol to determine whether NAMPT blockade enhances cytotoxic and immunomodulatory responses.\nMethods: Human and murine PDAC cell lines (PANC-1, MIA PaCa-2, KPC-Luc, and patient-derived 2838c) were treated with NAMPTi (5 μM) alone or with SOC agents at clinically relevant doses. Synergy was assessed in 2D viability and 3D spheroid assays. Olaparib combinations were also tested in BRCA-related models. In vivo, KPC allografts received NAMPTi (20 mg/kg, 5×/week) with gemcitabine, paclitaxel, hydroxychloroquine, 5-FU, oxaliplatin, or paricalcitol for three weeks. Immune infiltrates (CD45+, CD8+, CD4+ subsets), functional markers (GZMB, CD107a, IFNγ, TNFα), and fibroblast subtypes (apCAF, myCAF, iCAF) were quantified by flow cytometry.\nResults: Across all PDAC models, NAMPTi alone produced modest growth inhibition, while combination treatment consistently outperformed monotherapies. NAMPTi synergized with gemcitabine-paclitaxel-hydroxychloroquine and gemcitabine-paclitaxel regimens, significantly reducing cell viability in both human and KPC-derived lines. In vivo, NAMPTi combinations markedly suppressed KPC tumor growth compared to SOC alone and reduced metastatic burden to liver and lung (e.g., GPH+NAMPTi: 60% metastasis-negative vs. 20-40% in monotherapy groups). Dual treatment increased CD8+ T-cell infiltration and effector phenotypes, enhanced cytotoxic function (GZMB+, CD107a+), and elevated IFNγ and TNFα production. NAMPTi also shifted fibroblast composition, with significant reductions in myCAFs and apCAFs, suggesting stromal remodeling. In FO and GPH regimens, combining NAMPTi produced superior tumor control, decreased immunosuppressive cell populations, and improved effector memory T-cell signatures.\nConclusions: NAMPT inhibition robustly enhances SOC chemotherapy efficacy in PDAC by simultaneously amplifying cytotoxic responses, remodeling the tumor immune microenvironment, and reducing metastatic spread. These findings support NAMPTi-based combinations as a promising therapeutic strategy and justify further translational development, including biomarker-driven clinical evaluation in PDAC.\n\"Generative AI was used for improving the language of the abstract\".", "source_company": "University of Alabama at Birmingham", "source_org_type": "大学", "row_number": 900, "target_meta": "NAMPT", "MOA_meta": "抑制剂"}, {"drug_name": "targeted protein degrader", "company": "NJ Bio, Inc.", "org_type": "公司", "target": "未披露", "modality": "degrader", "importance_level": "中", "total_score": 57, "institution_score": 45, "track_score": 90, "milestone_score": 35, "field_heat_score": 85, "bonus_score": 3, "brief_reason": "该研究聚焦靶向蛋白降解（TPD/degrader）领域热门赛道，利用NMR表征三元复合物形成与动态，为下一代TPD设计提供新策略，但未披露具体靶点或化合物，仅为方法学研究。机构为专注ADC/TPD服务的CRO，非主流药企，preclinical工具性工作开发阶段较早。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6545", "id": "u1XM_5wBX1NQZOEH-LS6", "source_drug_name": "targeted protein degrader", "title": "NMR assessment of ternary complex formation by targeted protein degraders", "abstract_text": "Targeted protein degradation (TPD) is an increasingly prominent therapeutic strategy for targeting systems previously thought to be undruggable. Unlike typical small molecule inhibitors or agonists, TPDs induce the degradation of specific proteins by forcing them into proximity with the cell’s native proteasomal degradation machinery. Many companies are rapidly developing new TPDs, and several degraders have reached clinical trials. From a chemistry standpoint, there are three main aspects of a TPD to study and optimize: 1) a ligand that binds and recruits a target protein, 2) a ligand that binds an E3 ligase, and 3) a linker that orients the two ligands and their associated proteins at the correct geometry for degradation. TPDs present a more complicated case of lead optimization than traditional programs since they bind simultaneously to two proteins forming a non-native protein:protein complex. The formation of these target protein-TPD-E3 ternary complexes is of particular interest in the field. As in any drug development program, knowing structural details of how TPDs bind to their target proteins provides critical information that may offer new and unique insights into future TPD design. Further, ideal TPDs allow for turnover of the degradation machinery, meaning that these molecules act catalytically to degrade more target protein at low concentrations, which complicates the desired kinetics for the formation and dissolution of ternary complexes. Recent work has shown that these complexes may be fundamentally dynamic and involve non-optimal interactions.\nNuclear magnetic resonance (NMR) spectroscopy is uniquely poised to study these TPD complexes since it can be used to study both the structure and dynamics of molecules in solution. We report our use of NMR to characterize ternary complexes consisting of a TPD bound to both its target protein and the E3. Using isotopically labeled proteins, we first study the TPD binary complexes to establish how each end of the TPD binds before assessing additional changes that occur in ternary complexes. With this approach, we have the capacity to discriminate between changes due to ligand binding and those due to novel protein-protein interactions between the target protein and the E3. We find that the presence of the second protein in the ternary complex affects how the TPD binds to each protein, suggesting that these experiments report on the cooperativity of binding and the possible structural basis of this cooperativity. We further explored the use of NMR data acquired across a series of TPDs with different linkers to guide our understanding of the idealized ternary complex structural ensemble when combined with traditional assays for degradation. The study of ternary complex dynamics using NMR offers a new strategy to allow for the design and optimization of the next generation of TPDs. We will be disclosing all the structures related to this study.", "source_company": "NJ Bio, Inc.", "source_org_type": "公司", "row_number": 969, "target_meta": "not available", "MOA_meta": "降解剂"}, {"drug_name": "Targeted Protein Degraders", "company": "Shanghai ChemPartner Co., Ltd.", "org_type": "公司", "target": "未披露", "modality": "other", "importance_level": "中", "total_score": 57, "institution_score": 45, "track_score": 95, "milestone_score": 35, "field_heat_score": 85, "bonus_score": 0, "brief_reason": "该条为针对靶向蛋白降解剂（TPD，包括Molecular Glues）的泛化高通量泛素化assay平台评估方法研究，未披露具体靶点或药物分子。赛道为当前最热门的蛋白降解领域但机构为CRO服务公司而非原研药企，摘要仅体现方法学优化而无具体里程碑进展。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8720", "id": "Op7M_5wBZznHJdnt_W3O", "source_drug_name": "Targeted Protein Degraders", "title": "Evaluation of targeted protein degraders using high-throughput ubiquitination assays for mechanistic and SAR analysis", "abstract_text": "Targeted Protein Degraders (TPDs) represent a paradigm shift from traditional occupancy-driven inhibition to event-driven pharmacology by harnessing the ubiquitin-proteasome system for selective protein elimination. Despite their therapeutic potential, the rational design of effective degraders, particularly Molecular Glues, remains a significant challenge due to the complex interplay between binding cooperativity, ubiquitination efficiency, and degradation kinetics. To better understand these mechanisms, we established a suite of preclinical assays to systematically evaluate TPD activity across key mechanistic steps, including ternary complex formation, ubiquitination induction, cellular uptake, and target protein degradation in cellular and in vivo models. During the early screening of degrader libraries, medicinal chemists require efficient methods to assess structure-activity relationships (SARs). Comparative studies revealed that the ubiquitination assay provides a more predictive measure of cellular degradation efficiency than ternary complex formation assays. While ternary complex assays characterize binding affinity, cooperativity, and complex stability among the target, degrader, and E3 ligase, they fail to capture conformational changes necessary for productive ubiquitination. Our data demonstrate that ubiquitination assays offer deeper mechanistic insights with high throughput and scalability, enabling rapid generation of robust datasets for data-driven SAR development. This approach effectively bridges the gap between structural optimization and functional outcomes, accelerating the rational design of next-generation degraders with improved potency and selectivity for therapeutic applications.", "source_company": "Shanghai ChemPartner Co., Ltd.", "source_org_type": "公司", "row_number": 988, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "AUTAC", "company": "Virginia Commonwealth University", "org_type": "大学", "target": "Mcl1", "modality": "AUTAC", "importance_level": "中", "total_score": 57, "institution_score": 35, "track_score": 85, "milestone_score": 55, "field_heat_score": 70, "bonus_score": 5, "brief_reason": "AUTAC为靶向自噬-溶酶体途径选择性降解Mcl1的新型嵌合体，在多发性骨髓瘤细胞中有效诱导细胞毒性，同时显著降低心脏毒性。大学机构得分较低，但新型自噬靶向降解机制+心脏保护优势使其赛道和bonus较高，整体处于中等重要性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6111", "id": "S57M_5wBZznHJdnt_W3O", "source_drug_name": "AUTAC", "title": "Therapeutic exploitation of AUTAC in hematologic malignancies with cardiac protection", "abstract_text": "Background: Myeloid cell leukemia-1 (Mcl1) is a critical member of the Bcl2 family that plays an essential role in regulating apoptosis and maintaining mitochondrial integrity, particularly within cardiac tissue. While Mcl1 overexpression is a major driver of resistance to multiple anticancer therapies, its pharmacologic inhibition has been hampered by dose-limiting cardiotoxicity, representing a significant and unresolved challenge in cardio-oncology. The development of safer therapeutic strategies that selectively target Mcl1 in cancer cells while sparing cardiac cells remains a high-priority goal. In this study, our group investigated a novel autophagy-targeting chimera (AUTAC) designed to selectively degrade Mcl1 via the autophagy-lysosomal pathway. We aimed to determine whether AUTAC could induce selective cytotoxicity in multiple myeloma cells while preserving cardiac cell viability and mitochondrial function.\nMethods: Multiple myeloma cell lines (U266B1, RPMI-8226) and cardiac cell lines (AC16, H9c2) were used as tumor and cardiac models, respectively. Cell viability was assessed using the CellTiter-Glo assay and IncuCyte live-cell imaging. Mitochondrial membrane potential was measured by TMRE fluorescence. Effects of AUTAC on Mcl1 and autophagy dynamics were evaluated by Western blotting, confocal microscopy, and inhibition studies with 3-methyladenine (3-MA) and chloroquine (CQ). To confirm autophagy dependence, ATG5 was knocked down using shRNA.\nResults: Treatment with AUTAC selectively induced lysosomal degradation of Mcl1, without detectable effects on other anti-apoptotic Bcl2 family members, including Bcl2 and BclxL. Pharmacological inhibition of autophagy with 3-MA (early-stage inhibitor) or CQ (late-stage inhibitor) effectively blocked AUTAC-mediated Mcl1 degradation, confirming that the process required an intact autophagy-lysosomal pathway. Furthermore, knockdown of ATG5 abolished Mcl1 reduction, reinforcing the autophagy dependence of this degradation mechanism. Functionally, AUTAC treatment led to a greater than 50% reduction in cell viability in U266B1 and RPMI-8226 multiple myeloma cells, accompanied by increased apoptotic signaling. In contrast, AUTAC caused minimal cytotoxicity in AC16 and H9c2 cells, maintaining mitochondrial function and morphology. Compared with conventional Mcl1 inhibitors, AUTAC exhibited substantially reduced cardiotoxicity, underscoring its favorable safety profile.\nConclusions: Targeted lysosomal degradation of Mcl1 via AUTAC represents a promising therapeutic strategy that repurposes autophagy for selective oncogenic protein removal. AUTAC effectively degraded Mcl1 in malignant cells while sparing cardiac cells from apoptosis and mitochondrial injury, highlighting its potential as a next-generation, cardio-safe alternative to conventional Mcl1 inhibitors.", "source_company": "Virginia Commonwealth University", "source_org_type": "大学", "row_number": 999, "target_meta": "MCL1", "MOA_meta": "AUTAC"}, {"drug_name": "CADM1-CAR T cells", "company": "University of Michigan", "org_type": "大学", "target": "CADM1", "modality": "CAR", "importance_level": "中", "total_score": 57, "institution_score": 35, "track_score": 85, "milestone_score": 55, "field_heat_score": 75, "bonus_score": 3, "brief_reason": "靶向CADM1的CAR-T细胞，针对神经内分泌型SCLC（ASCL1/NEUROD1亚型），赛道为热门的CAR细胞治疗且靶点具特异性。大学机构分数较低，但体外强效+体内显著抑瘤和生存获益显示较好preclinical强度，综合热度和潜力中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5196", "id": "q57M_5wBZznHJdnt_W3O", "source_drug_name": "CADM1-CAR T cells", "title": "CADM1-CAR T cells targeting neuroendocrine subtypes of small cell lung cancer", "abstract_text": "Small cell lung cancer (SCLC), accounting for approximately 15% of all lung cancer cases, represents an aggressive carcinoma characterized by rapid proliferation, early dissemination, and the development of therapeutic resistance. Recent transcriptomic profiling has delineated SCLC into distinct molecular subtypes defined by the expression of lineage-specifying transcription factors ASCL1, NEUROD1, YAP1, and POU2F3. Among these, the neuroendocrine subtypes SCLC-A (ASCL1-driven) and SCLC-N (NEUROD1-driven) predominate in 80% of patient populations. Due to the intrinsically low expression of major histocompatibility complex (MHC) molecules and the consequent poor responsiveness to immune checkpoint blockade, the development of MHC-independent immunotherapeutic strategies is imperative for SCLC. Cell Adhesion Molecule 1 (CADM1), a membrane glycoprotein with context-dependent tumor suppressor and pro-tumorigenic functions, is aberrantly expressed in SCLC and implicated in regulating cellular adhesion, immune evasion, and metastatic dissemination. Our analyses revealed that CADM1 expression inversely correlates with MHC expression scores and is enriched in treatment-naïve tumors with high neuroendocrine differentiation (ASCL1- and NEUROD1-dominant subtypes). The overexpression of CADM1 in tumor cells, makes it an attractive target for antigen-specific immunotherapy. To exploit this vulnerability, we engineered a CADM1-specific chimeric antigen receptor (CADM1-CAR) T cell. CADM1-CAR T cells exhibited robust antigen-dependent cytotoxicity, enhanced secretion of effector cytokines (IFN-γ, TNF-α), and upregulation of cytolytic mediators (granzyme A/B, perforin), resulting in potent SCLC cell lysis in vitro. In NSG mice bearing disseminated H82 xenografts, CADM1-CAR T cell treatment significantly inhibited tumor progression and extended overall survival. These findings establish CADM1 as a promising tumor-associated antigen and support the therapeutic potential of CADM1-targeted CAR T cell therapy for high-grade neuroendocrine SCLC.", "source_company": "University of Michigan", "source_org_type": "大学", "row_number": 1070, "target_meta": "CADM1", "MOA_meta": "其他"}, {"drug_name": "CD19-targeted CAR T cells", "company": "Reaction Biology Europe GmbH", "org_type": "公司", "target": "CD19", "modality": "CAR", "importance_level": "中", "total_score": 57, "institution_score": 45, "track_score": 85, "milestone_score": 40, "field_heat_score": 75, "bonus_score": 0, "brief_reason": "该项针对CD19 CAR-T细胞的体外疲竭模型开发，靶点为CD19，modality为CAR，属于细胞治疗热门赛道，但机构为CRO服务公司而非药物研发主体，摘要仅描述工具/assay方法，无具体药物优化里程碑或临床推进。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/7226", "id": "9J7M_5wBZznHJdnt_W3O", "source_drug_name": "CD19-targeted CAR T cells", "title": "Development of an in vitro exhaustion assay for functional screening of CAR T cell enhancements", "abstract_text": "Chimeric antigen receptor (CAR) T cells have emerged as a powerful tool in cancer immunotherapy, particularly in hematologic malignancies such as B-cell leukemia and lymphoma. CAR T cell therapy involves genetically engineering patient-derived T cells to express synthetic receptors that target tumor-associated antigens, enabling precise and potent immune responses against cancer cells. Despite remarkable clinical successes, especially with CD19-targeted CAR T cells, the therapy has limitations that hinder broader application and long-term efficacy. A significant challenge is T cell exhaustion, a dysfunctional state involving reduced proliferation, diminished cytokine production, and impaired cytotoxicity. Exhaustion often arises in the tumor microenvironment, where persistent antigen stimulation, immunosuppressive signals, and metabolic stress collectively impair CAR T cell function. This limits durability and contributes to relapse in many patients. Overcoming CAR T cell exhaustion is essential to improving efficacy and durability of cellular therapies. Strategies under investigation include optimizing CAR architecture by using alternative co-stimulatory domains, transiently modulating inhibitory pathways, and refining manufacturing protocols to preserve T cell fitness.\nAn in vitro assay that reliably mimics exhaustion is essential for identifying and validating improvements. In this study, we present several approaches to inducing exhaustion-like phenotypes in CAR T cells. Chronic, antigen-agnostic stimulation and repeated co-culture with antigen-expressing target cells are used to model persistent activation, and to compare various functional readouts. We discuss the advantages and limitations of different assay setups to help identify the most suitable approach depending on the specific experimental needs. A robust and reproducible assay system is key to reliably screening novel CAR T cell designs and therapeutic interventions aimed at mitigating T cell exhaustion. We compare T cell functionality using multiple readout technologies, including impedance-based measurements using xCelligence for adherent and selected suspension cells and luminescence assays with luciferase-expressing target cells as well as flow cytometry. This allows us to highlight the strengths and constraints of each method in capturing functional decline and exhaustion phenotypes.\nOur findings support the use of standardized in vitro exhaustion models as valuable tools for the preclinical evaluation of next-generation CAR T cell therapies and combination strategies. Furthermore, our antigen-agnostic model enables evaluation of the impact of any T cell modulation approach on exhaustion dynamics. These models enable more predictive and efficient development of strategies to enhance therapeutic performance.", "source_company": "Reaction Biology Europe GmbH", "source_org_type": "公司", "row_number": 1121, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "SY-14556", "company": "Shouyao Holding (Beijing) Co., Ltd.", "org_type": "公司", "target": "p53 Y220C mutant", "modality": "small molecule reactivator", "importance_level": "中", "total_score": 57, "institution_score": 60, "track_score": 50, "milestone_score": 30, "field_heat_score": 85, "bonus_score": 3, "brief_reason": "p53 Y220C是一个热门靶点，已有临床POC（rezatapopt/rezatapopt在2026年仍在积极开发，phase 2数据积极，多瘤种响应），领域热度高；SY-14556展示极高生化/细胞 potency (EC50 <5nM/<50nM, IC50 20-100nM, >100x selectivity)，体内CDX模型robust efficacy，PK/耐受好，被宣称为best-in-class；但公司为中国Biotech，track record有限，无任何临床进展迹象，仍处preclinical (AACR 2026 poster)，milestone仅discovery presentation，得分中等偏上。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8830", "id": "kFXM_5wBX1NQZOEH-LO6", "source_drug_name": "SY-14556", "title": "Discovery of SY-14556, a highly potent and selective small molecule reactivator of p53 Y220C mutant with differentiated preclinical profile", "abstract_text": "As a key tumor suppressor, p53 binds to DNA and transcriptionally activates target genes to regulate cell-cycle arrest, DNA damage repair, apoptosis, and multiple other antiproliferative processes. TP53 is the most frequently mutated gene in human cancer, and Y220C is one hot-spot mutation occurring in approximately 1% of solid tumors. Pharmacologic stabilization and reactivation of the Y220C mutant to a wild-type-like conformation is a validated therapeutic strategy, as demonstrated by the clinical activity of PC14586 (rezatapopt). Here, we characterize SY-14556 as a highly potent and selective p53 Y220C reactivator. In biochemical assay, SY-14556 induced p53 Y220C DNA binding with an EC50 < 5 nM. In luciferase reporter assay, SY-14556 activated wild-type p53 transcriptional activity with an EC50 < 50 nM. Across a panel of p53 Y220C-mutant cancer cell lines, SY-14556 inhibited proliferation (IC50 20-100 nM) with >100-fold selectivity over p53-WT cells. Consistent with high-fidelity p53 pathway reactivation, SY-14556 also dose-dependently activated p53 target genes expression including p21 and MDM2, inducing cell cycle arrest and apoptosis. In vivo, SY-14556 demonstrated robust anti-tumor activity in several p53 Y220C-mutant cell line-derived xenograft (CDX) models. Furthermore, SY-14556 displayed favorable PK properties and tolerability in preclinical studies. In conclusion, SY-14556 is a best-in class p53-Y220C reactivator with robust preclinical efficacy and safety. These data support its advancement into clinical trials for p53 Y220C-mutant solid tumors.", "source_company": "Shouyao Holding (Beijing) Co., Ltd.", "source_org_type": "公司", "row_number": 1242, "target_meta": "p53 Y220C", "MOA_meta": "重活化剂"}, {"drug_name": "vizenpistat", "company": "Stingray Therapeutics", "org_type": "公司", "target": "ENPP1", "modality": "inhibitor", "importance_level": "中", "total_score": 57, "institution_score": 45, "track_score": 75, "milestone_score": 50, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "vizenpistat为口服ENPP1抑制剂，通过负调控cGAS-STING通路激活先天免疫抗肿瘤响应，靶点创新且与免疫治疗相关。Stingray Therapeutics为小型biotech公司，已进入I期临床但非头部机构，赛道热度较高但里程碑仍处早期导致总分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/12106", "id": "UlXM_5wBX1NQZOEH-LK6", "source_drug_name": "vizenpistat", "title": "Phase I dose-escalation study of ENPP1 inhibitor, vizenpistat, for the treatment of solid tumors", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Stingray Therapeutics", "source_org_type": "公司", "row_number": 1268, "target_meta": "ENPP1", "MOA_meta": "抑制剂"}, {"drug_name": "cyclic-di-GMP", "company": "Navicyte Biotechnologies LLC", "org_type": "公司", "target": "STING", "modality": "other", "importance_level": "中", "total_score": 56.5, "institution_score": 45, "track_score": 75, "milestone_score": 55, "field_heat_score": 70, "bonus_score": 2, "brief_reason": "cyclic-di-GMP作为STING激动剂，通过T3MPs淋巴细胞仿生递送平台靶向肿瘤引流淋巴结实现免疫激活。Navicyte为早期初创biotech公司，平台创新性强但仍处preclinical向IND推进阶段，STING通路在免疫治疗领域热度较高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5561", "id": "up7M_5wBZznHJdnt_W3O", "source_drug_name": "cyclic-di-GMP", "title": "Lymphocyte-mimetic drug carriers enable targeted therapeutic delivery to lymph nodes for enhanced immunomodulation", "abstract_text": "Introduction: Immunotherapy efficacy in solid tumors is often limited by immune tolerance within tumor-draining lymph nodes (TDLNs), where antigen presentation and T-cell priming originate. Immune activators, such as STING agonists, are capable of reversing local immunosuppression, however their clinical translation has been hindered by rapid systemic clearance, dose-limiting toxicity, and poor lymph node bioavailability. Effective targeting of TDLNs could overcome these translational barriers by reprogramming local immune environments and amplifying durable antitumor immunity. To address this, we have developed a novel delivery platform T-Lymphocyte Mimetic Membrane-wrapped Microparticles (T3MPs).\nMethods: T3MPs were fabricated using a flow-focusing microfluidic device to generate uniform, cell-sized alginate microparticles (10-20 µm). Multiple payloads, including cyclic-di-GMP (STING agonist) and cisplatin, were encapsulated within the alginate matrix during particle formation. Drug-loaded T3MPs were cloaked with allogenic T-cell membranes to preserve trafficking proteins, confirmed via flow cytometry. Drug encapsulation and release kinetics were quantified via spectrofluorometry. In vitro payload functionality was assessed with THP-1 culture, and in vivo biodistribution and efficacy were evaluated following intravenous administration in BALB/c mice.\nResults: T3MPs exhibited uniform size distribution and retained key lymphocyte surface proteins (L-selectin, LFA-1) critical for LN trafficking and demonstrated tunable, sustained drug release, achieving ~50% release over 10 days in vitro. Following intravenous administration, drug-loaded T3MPs achieved ~700% greater LN-specific delivery than free drug controls and extended the therapeutic index >500-fold by reducing systemic exposure. Delivery of c-di-GMP via T3MPs induced potent activation of lymph node resident antigen presenting cells (elevated IFN-β and IL-12), while co-delivery of c-di-GMP and model tumor antigen (SIINFEKL) enhanced antigen-specific CD8⁺ T-cell priming.\nConclusions: T3MPs represent a novel lymphocyte-mimetic platform that overcomes pharmacological barriers to lymph node drug delivery, enabling safe, localized immunomodulation for reprogramming immune niches. By combining lymphocyte-inspired targeting with tunable release, this technology offers a broadly applicable strategy to enhance the efficacy of immunotherapies and vaccines. Ongoing work through Navicyte Biotechnologies is advancing the T3MP platform toward IND-enabling studies and strategic pharmaceutical partnerships.", "source_company": "Navicyte Biotechnologies LLC", "source_org_type": "公司", "row_number": 89, "target_meta": "STING", "MOA_meta": "其他"}, {"drug_name": "8E11-CPT2", "company": "The University of Texas MD Anderson Cancer Center UTHealth Houston Graduate School of Biomedical Sciences", "org_type": "大学", "target": "LGR5", "modality": "ADC", "importance_level": "中", "total_score": 56.5, "institution_score": 35, "track_score": 80, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "8E11-CPT2为靶向LGR5的ADC，联合MET ADC显示协同抗CRC耐药潜力。大学机构分数较低，但ADC+热门CSC靶点+耐药机制突破获较高赛道与里程碑分，综合重要性中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5365", "id": "9VXM_5wBX1NQZOEH-LK6", "source_drug_name": "8E11-CPT2", "title": "Targeting MET-LGR5 crosstalk using an antibody-drug conjugate combination with diverse payloads to overcome adaptive resistance in colorectal cancer", "abstract_text": "Off-target side effects and drug resistance often hamper the therapeutic benefits of existing anti-cancer therapies against colorectal cancer (CRC), the second deadliest malignancy worldwide. CRCs contain tumor-initiating cancer stem-like cells (CSCs) that survive toxic drugs and give rise to metastatic disease. Antibody-drug conjugates (ADCs) are a revolutionary class of therapeutics that leverage monoclonal antibody (mAb) specificity to deliver cytotoxic payloads to tumor cells. We generated ADCs targeting leucine-rich repeat-containing G protein-coupled receptor 5 (LGR5), a bona fide CSC biomarker frequently overexpressed in CRCs. Our LGR5 ADC exhibited high potency in CRC xenograft models with minimal toxicity. However, it failed to prevent tumor relapse after treatment cessation. Interestingly, we found that recurrent tumors evade LGR5 ADC-mediated elimination by transiently converting into an LGR5-negative (LGR5-) state, accompanied by concomitant MET upregulation and activation of the downstream pathway. MET is a receptor tyrosine kinase frequently upregulated in CRCs and promotes metastatic progression. We identified that the activation of STAT3, a downstream effector protein in the MET pathway, undermines LGR5 ADC efficacy in CRC cells. To eliminate drug-resistant LGR5- cells, we generated MET-targeted ADCs by attaching a highly selective MET mAb (ABT700) backbone to the DNA-crosslinking payload pyrrolobenzodiazepine (PBD) via site-specific conjugation. This MET ADC (ABT700-PBD) demonstrated dose-dependent cytotoxicity in CRC cells. Furthermore, ABT700-PBD did not affect CRC cells with genetically induced MET ablation, demonstrating its specificity. Safety studies in immunocompetent mice showed that ABT700-PBD exhibited a favorable safety profile. Moreover, in CRC xenograft models, ABT700-PBD induced marked tumor regression. However, in the residual tumors following dose-dependent ABT700-PBD monotherapy, LGR5 protein expression was upregulated. These observations suggest that the MET-LGR5 crosstalk may be a potential driver of adaptive resistance in CRC. Cytotoxicity assays testing ABT700-PBD and our previously reported camptothecin-derived (CPT2) LGR5-targeted ADC (8E11-CPT2) demonstrated synergistic cell-killing activity in vitro. Combination treatment with ABT700-PBD and 8E11-CPT2 in CRC patient-derived xenograft models extended survival compared to single-agent ADCs. Collectively, our findings support MET and LGR5 ADC combination therapy as a novel treatment strategy to overcome adaptive resistance-driven relapse in CRC.", "source_company": "The University of Texas MD Anderson Cancer Center UTHealth Houston Graduate School of Biomedical Sciences", "source_org_type": "大学", "row_number": 646, "target_meta": "LGR5", "MOA_meta": "抗体偶联药物"}, {"drug_name": "STING agonists", "company": "The Walter & Eliza Hall Institute of Medical Research", "org_type": "研究机构", "target": "cGAS/STING pathway", "modality": "other", "importance_level": "中", "total_score": 56.5, "institution_score": 35, "track_score": 75, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "STING激动剂通过p53独立途径上调促凋亡BH3-only蛋白，与BH3模拟物联用可有效杀伤p53突变血液瘤细胞。该工作来自知名学术研究机构，机制有创新但仍处preclinical概念验证阶段，整体重要性中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/472", "id": "BlXM_5wBX1NQZOEH-LS6", "source_drug_name": "STING agonists", "title": "Boosting the efficacy of BH3 mimetic drugs for cancer therapyy", "abstract_text": "Enhancing BH3 mimetic drug induced killing of malignant cells for cancer therapy\nSarah T Diepstraten, John E La Marca, Yin Yuan, Fiona C Brown, Andrew W Roberts, Andrew H Wei, Gemma L Kelly, Andreas Strasser* (*presenting author)\nThe Walter and Eliza Hall Institute of Medical Research, Melbourne, Australia\nBH3 mimetic drugs are showing great success in the clinic, particularly in hematological cancers. However, p53-mutant hematological cancers remain a major clinical challenge and BH3 mimetic drugs have not shown marked single-agent effects in solid cancers. BH3-mimetic drugs inhibit BCL-2 pro-survival proteins to promote cancer cell apoptosis. Despite acting downstream of the tumor suppressor p53 (TP53, TRP53), functional p53 is required for maximal cancer cell killing by BH3-mimetic drugs. Here, we report that p53 can be activated following BH3-mimetic induced mitochondrial outer membrane permeabilization, which leads to further induction of BH3-only proteins, thereby potentiating the pro-apoptotic signal. p53-deficient blood cancers lack this feed-forward loop, providing opportunities for survival and disease relapse after BH3-mimetic treatment. Of note, the therapeutic barrier imposed by defects in p53 could be overcome by direct activation of the cGAS/STING pathway in malignant cells. This causes killing of blood cancer cells through p53-independent up-regulation of pro-apoptotic BH3-only proteins. Combining clinically relevant STING agonists with BH3-mimetic drugs efficiently killed p53-mutant mouse B lymphoma, human extranodal NK/T lymphoma and human acute myeloid leukemia cells. This represents a promising therapy regime that can be fast-tracked to tackle p53-mutant blood cancers, and possibly also other cancers, in the clinic.", "source_company": "The Walter & Eliza Hall Institute of Medical Research", "source_org_type": "研究机构", "row_number": 834, "target_meta": "cGAS,STING", "MOA_meta": "其他"}, {"drug_name": "first-in-class small-molecule SPNS2 inhibitor", "company": "The Medical University of South Carolina", "org_type": "大学", "target": "SPNS2", "modality": "inhibitor", "importance_level": "中", "total_score": 56.5, "institution_score": 35, "track_score": 75, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "该first-in-class小分子SPNS2抑制剂通过诱导免疫原性细胞死亡（ICD）并激活系统性抗肿瘤免疫显著抑制转移，靶向SPNS2-S1P轴具有新机制潜力；大学机构得分较低，但热门免疫-转移机制+preclinical强数据+ICD+疫苗保护效应带来较高赛道与里程碑价值。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/12391", "id": "I1XM_5wBX1NQZOEH-LS6", "source_drug_name": "first-in-class small-molecule SPNS2 inhibitor", "title": "Targeting Spns2 induces immunogenic cell death and systemic anti-tumor immunity to suppress metastasis", "abstract_text": "Background: Spinster homolog 2 (SPNS2) exports sphingosine-1-phosphate (S1P) to promote oncogenic signaling. Although SPNS2 is associated with metastatic progression, its tumor-intrinsic role in regulating immunogenic cell death (ICD) and anti-tumor immunity remains unclear. We examined how genetic or pharmacologic inhibition of SPNS2 influences metastasis, ICD induction, and systemic immune activation.\nMethods: Patient datasets were analyzed in conjunction with breast (4T1, EMT6) and melanoma (B16) models. SPNS2 was ablated using CRISPR or inhibited using a first-in-class small-molecule SPNS2 inhibitor. S1P export, migration, and S1PR1-AKT signaling were assessed in vitro. Orthotopic, tail-vein, co-injection, and vaccination models were used to evaluate tumor growth, metastatic spread, ICD signatures, and systemic immunity. Individual DAMP pathways were disrupted to test mechanistic requirements.\nResults: High SPNS2 expression correlated with poor survival across multiple cancer types. SPNS2 promoted S1P export, S1PR1-AKT activation, epithelial-mesenchymal transition, stemness, and lung colonization, whereas SPNS2 loss impaired migration and markedly reduced spontaneous and experimental metastases. SPNS2 inhibition elicited hallmark ICD features—including eIF2α phosphorylation, calreticulin exposure, and ATP/HMGB1 release—enhancing antigen presentation, expanding CD4⁺ and CD8⁺ T cells, and limiting primary tumor growth, metastasis, and postsurgical relapse. Vaccination with SPNS2-deficient or inhibitor-treated tumor cells protected against rechallenge with 4T1 or antigenically distinct EMT6 tumors. Disruption of individual DAMP pathways attenuated these responses, demonstrating ICD dependence. Conclusions: SPNS2-mediated S1P transport drives metastasis and immune evasion, whereas SPNS2 inhibition induces ICD and potent systemic T-cell immunity. Targeting SPNS2 represents a therapeutic strategy to suppress metastatic progression and generate durable anti-tumor immunity.\nDisclosure: Generative AI was used to assist in editing this abstract.", "source_company": "The Medical University of South Carolina", "source_org_type": "大学", "row_number": 854, "target_meta": "SPNS2", "MOA_meta": "抑制剂"}, {"drug_name": "Menin inhibitors", "company": "Peter MacCallum Cancer Centre", "org_type": "医院", "target": "Menin", "modality": "inhibitor", "importance_level": "中", "total_score": 56.5, "institution_score": 35, "track_score": 75, "milestone_score": 70, "field_heat_score": 65, "bonus_score": 2, "brief_reason": "Menin抑制剂通过破坏Menin-MLL1相互作用调控IRF4超级增强子，在多发性骨髓瘤模型中显示显著抗肿瘤活性。机构为医院/研究型癌症中心而非头部药企导致机构分较低，但靶点机制新颖且preclinical数据较扎实，综合赛道与潜力打分为中。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8667", "id": "Jp7M_5wBZznHJdnt_W7O", "source_drug_name": "Menin inhibitors", "title": "Targeting the epigenetic adaptor protein menin in multiple myeloma", "abstract_text": "The interaction between the epigenetic proteins Menin and MLL1 is critical for sustaining the expression of self-renewal genes in specific subsets of acute leukemias. Disrupting the Menin-MLL1 interaction with Menin inhibitors (iMenin) is showing promising overall response rates in leukemia clinical trials, however, iMenin are not known to be active in other cancers. We analysed DepMap and discovered that many multiple myeloma (MM) cell lines are highly dependent on Menin/MLL1 for proliferation. MM is a common plasma cell malignancy that remains largely incurable, despite the plethora of treatments available. The objectives of our study are to understand the role of the Menin/MLL1 complex in MM, determine the efficacy of iMenin in MM pre-clinical models and identify biomarkers of response to enable the rapid and successful translation of iMenin into the myeloma setting.\nTo assess the efficacy of iMenin in MM, we performed growth assays across 13 commercially available cell lines and 9 early passage patient-derived MM cells (physiologically relevant model). We found that ~30% were highly sensitive to iMenin with a substantial impact on viability and proliferation, with an additional ~40% showing a significant anti-proliferative response. Sensitivity was significantly correlated with the absence of the MYC t(8;14) translocation. Importantly, iMenin showed in vivo efficacy in a xenograft and in the syngeneic Vk*MYC-32052 model of MM.\nRNA-, ChIP- and chromatin conformation sequencing found that iMenin sensitivity was characterized by the deposition of Menin/MLL1 at the super-enhancer of IRF4, with iMenin evicting Menin/MLL1 from chromatin and suppressing IRF4 and its target genes. Genome-wide CRISPR screening was performed to identify the molecular determinants of iMenin response in MM. This identified the EP300/CREBBP/NCOR1 axis as a key modulator of iMenin sensitivity. To further advance the translational potential of iMenin, we tested several combination strategies. Among the most effective was the combination of Menin and EP300/CREBBP inhibitors, which demonstrated synergistic activity even in models which were unresponsive to the single-agents, including JJN3 cells in vitro and the syngeneic in vivo Vk*MYC-14551 model. Molecular analyses uncovered deep suppression of IRF4, via disruption of the canonical IRF4 super-enhancer, as the mechanism underpinning the synergy between Menin and EP300/CREBBP inhibitors.\nTaken together, Menin regulates the pan-myeloma essential transcription factor IRF4 and is a promising and clinically actionable target in MM.", "source_company": "Peter MacCallum Cancer Centre", "source_org_type": "医院", "row_number": 1149, "target_meta": "menin", "MOA_meta": "抑制剂"}, {"drug_name": "OMTX105", "company": "Agencia Estatal Consejo Superior De Investigaciones Cientificas", "org_type": "研究机构", "target": "FAP", "modality": "ADC", "importance_level": "中", "total_score": 56.5, "institution_score": 35, "track_score": 85, "milestone_score": 55, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "OMTX105为靶向FAP的ADC，通过不同linker-payload设计展现更强旁观者杀伤和快速处理特性，在异种移植模型中抗肿瘤活性较高，但治疗窗较窄。机构为西班牙国家级研究机构而非商业biopharma导致institution_score偏低，ADC+FAP靶点在肿瘤微环境领域热度高，但仅preclinical表征无临床数据使总分处于中等水平。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9661", "id": "sVXM_5wBX1NQZOEH-LS6", "source_drug_name": "OMTX105", "title": "Mechanistic drivers of FAP-targeted ADC performance", "abstract_text": "Cancer-associated fibroblasts (CAFs), the main stromal cell population within the tumor microenvironment (TME), play a pivotal role in cancer progression, metastasis, and immune evasion. To target this compartment, two antibody-drug conjugates (ADCs), OMTX705 and OMTX105, were developed against fibroblast activation protein (FAP) expressed on CAFs. Both share the same human IgG1 antibody backbone (OMTX005) but differ in linker-payload chemistry: OMTX705 carries the cytolysin A1B1, whereas OMTX105 includes monomethyl auristatin E (MMAE). Despite similar drug-antibody ratios (DAR ≈ 4), their distinct vc-PABA-derived linkers confer differential stability and intracellular processing characteristics.We performed a comprehensive characterization of their mechanisms of action, including internalization, intracellular trafficking, and bystander cytotoxicity, in vitro and in vivo, as well as plasma stability and maximum tolerated dose (MTD) analyses to assess their pharmacological and safety profiles. Both ADCs displayed potent antitumor effects but differed markedly in their intracellular fate and pharmacodynamic properties. OMTX105 demonstrated faster processing and stronger bystander killing, leading to higher antitumor activity in murine xenografts; however, its effective dose was close to the MTD in rat, limiting its therapeutic window. In contrast, OMTX705 exhibited slower intracellular processing, resulting in a sustained and controlled payload release. This translated into a longer-lasting effect in vivo, with CAFs acting as a drug reservoir prolonging cytotoxic activity in neighboring tumor cells, while maintaining a superior safety profile.Remarkably, both ADCs exhibited in humanized xenograft mice a shared immunomodulatory activity, promoting infiltration of CD4⁺ and CD8⁺ T lymphocytes within the TME—particularly CD8⁺ cells in treated tumors—suggesting that FAP-targeted ADCs facilitate immune cell recruitment compared to control. This was confirmed in clinical samples from patients treated with OMTX705, currently under clinical development. In these patients, CAF disruption, much lower FAP expression and higher CD8⁺ and CD4+ cell infiltration was detected in tumor areas co-localizing with the OMTX705 payload signal, providing evidence that OMTX705 enhances local immune activation and supports an antitumor immune response.Overall, these findings reveal both cytotoxic and immunomodulatory functions for FAP-targeted ADCs within the TME and provide molecular mechanistic insights into their bystander effect, emphasizing how differences in linker-payload chemistry critically determine efficacy, durability of response, immune engagement, and tolerability. This study highlights OMTX705 potential as a safer FAP-targeted ADC with long-lasting effect and underlines the importance of biology-driven linker-payload engineering for next-generation stroma-directed ADC anticancer therapies.", "source_company": "Agencia Estatal Consejo Superior De Investigaciones Cientificas", "source_org_type": "研究机构", "row_number": 1238, "target_meta": "FAP", "MOA_meta": "抗体偶联药物"}, {"drug_name": "ERK2-DBP domain selective inhibitors", "company": "Fox Chase Cancer Center", "org_type": "研究机构", "target": "ERK2 DBP domain", "modality": "inhibitor", "importance_level": "中", "total_score": 56, "institution_score": 35, "track_score": 75, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "药物针对ERK2的DBP结构域进行选择性抑制，可阻断PDAC进展并调控c-Myc及免疫微环境，机制新颖且具双重调控潜力。机构为研究机构得分较低，但靶点/机制在MAPK通路中具差异化价值，处于早期验证阶段。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4412", "id": "N57ECZ0BZznHJdntvNYd", "source_drug_name": "ERK2-DBP domain selective inhibitors", "title": "Modular control of Pancreatic ductal adenocarcinoma (PDAC) progression by the substrate interaction domains of ERK2", "abstract_text": "Background: PDAC is a lethal disease with 5-year survival rate of just 13%, in desperate need of new therapeutic interventions. The primary driver of PDAC pathogenesis is the KRAS; however, current therapeutics targeting the activities of components of the KRAS/MAPK pathway fail to provide lasting benefit. We hypothesize that this results from active-site directed drugs attenuating the function of both substrate binding domains of ERK, which perform opposing roles in cancer pathogenesis. In myeloproliferative neoplasms, the ERK2-D domain promotes, and the ERK2-DBP domain impedes progression. Consequently, attenuating RAS/MAPK activity is akin to pressing both the gas and brake pedals on an automobile. Here we investigated the possibility that ERK signaling may also have cancer promoting and opposing roles in PDAC.\nMethods: Here, we seek to determine which ERK family member (ERK1 or ERK2) is the primary driver of PDAC pathogenesis and if the ERK D and DBP substrate domains play opposing roles. To do so, we utilize the KPC-PDAC mouse model and cross it to mice deficient in ERK1, ERK2, or an ERK2-DBP mutant to assess the impact on PDAC pathogenesis. We also utilized an ERK2 allelic series of isogenic KPC mouse cell lines (FC1245) to study the impact of ERK2-D and DBP mutants on pathogenesis in vitro and upon transplantation into mice.\nResults: We found that while ERK1 loss had no impact on PDAC pathogenesis, ablation of ERK2 markedly attenuated PDAC progression in KPC mice, indicating that ERK2 is primarily responsible for progression. Moreover, we found that inactivation of the ERK2-DBP domain was sufficient to delay PDAC progression to the same degree as ablation of ERK2. Attenuation of PDAC progression by ERK2-DBP mutation was associated with reduced expression and nuclear localization of c-Myc, a critical driver of PDAC progression. In addition to the cell autonomous effects of the ERK2-DBP mutation on PDAC, we also found differences in tumor-infiltrating immune cells, including fewer phenotypic myeloid derived suppressor cells and reduced expression of Tim3 on infiltrating T cells. The DBP mutation also attenuated colony formation in vitro, however, this was not observed for the ERK2-D domain, suggesting distinct functions in pathogenesis by the two ERK2 substrate domains. To investigate the therapeutic implications, we tested the efficacy of ERK2-DBP domain inhibitors to attenuate PDAC growth in vitro and in initial studies, determined that PDAC growth was substantially inhibited by DBP domain selective inhibitors.\nConclusion: ERK2 DBP is the domain responsible for PDAC progression and its inactivation delays tumor development. We are now using generative modeling to identify DBP inhibitors that have superior efficacy and ability to co-modulate the cell-autonomous effects on PDAC growth and the cell extrinsic effects on the immune system, alone and in combination with immune interventions.", "source_company": "Fox Chase Cancer Center", "source_org_type": "研究机构\n医院", "row_number": 411, "target_meta": "ERK2", "MOA_meta": "抑制剂"}, {"drug_name": "VJDT", "company": "Augusta University", "org_type": "大学", "target": "TREM1", "modality": "inhibitor", "importance_level": "中", "total_score": 56, "institution_score": 35, "track_score": 75, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "VJDT为TREM1小分子抑制剂，可抑制肝癌干细胞自我更新和肿瘤发生，展现肿瘤内在调控作用。机构为大学非商业研发得低分，靶点TREM1在肿瘤免疫和干性领域有新兴热度但非最热门，摘要显示pharmacologic inhibition与genetic knockout表型一致且有in vivo验证得中等里程碑分。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/683", "id": "pJ3ECZ0B4z9FlvORyiZD", "source_drug_name": "VJDT", "title": "Trem1 sustains liver cancer stemness in hepatocellular carcinoma", "abstract_text": "Hepatocellular carcinoma (HCC) is the most common primary liver malignancy and a leading cause of cancer-related mortality worldwide. Although the Triggering Receptor Expressed on Myeloid Cells 1 (TREM1) is well known for shaping tumor-infiltrating myeloid populations and promoting an immunosuppressive tumor microenvironment, its tumor-intrinsic function remains poorly defined. Here, we identify a previously unknown function of TREM1 in sustaining the stem-like properties of liver cancer stem-like cells (LCSLCs). Flow cytometric analyses revealed high TREM1 expression within the CD133⁺EpCAM⁺ LCSLC population. CRISPR-Cas9-mediated knockout of TREM1 in HCC cell lines markedly impaired proliferation and migration while enhancing apoptosis. Specifically, in LCSLCs TREM1 deficiency reduced clonogenic growth and spheroid formation, indicating loss of self-renewal and stemness. Consistently, cell line-derived xenografts generated from TREM1-deficient LCSLCs exhibited substantially diminished tumorigenicity in vivo. Transcriptomic profiling of FACS purified LCSLCs demonstrated that TREM1 loss disrupted various nuclear and extracellular signaling programs associated with oncogenic and stemness pathways. Moreover, pharmacologic inhibition of TREM1 using the small-molecule antagonist VJDT phenocopied the tumor-suppressive effects observed in genetic knockout models. Collectively, these findings establish TREM1 as a critical intrinsic regulator of LCSLC survival and tumorigenic potential, independent of its immunomodulatory activity in the tumor microenvironment. Therapeutically, targeting TREM1 may offer a dual-action approach to simultaneously suppress cancer stem-like cell function and attenuate cancer progression in HCC.", "source_company": "Augusta University", "source_org_type": "大学", "row_number": 1045, "target_meta": "TREM1", "MOA_meta": "抑制剂"}, {"drug_name": "SH6", "company": "Brigham and Women's Hospital", "org_type": "医院", "target": "SALL4", "modality": "degrader", "importance_level": "中", "total_score": 56, "institution_score": 35, "track_score": 75, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "SH6为新型小分子SALL4降解剂，针对HMA治疗后异常上调的癌胚基因SALL4，在MDS细胞模型中逆转HMA耐药并增强细胞毒性。机构为医院得分较低，但靶点新颖机制+degrader模态热度较高，preclinical数据较扎实，综合重要性中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8575", "id": "qJ7M_5wBZznHJdnt_W3O", "source_drug_name": "SH6", "title": "HMA-induced oncogene reactivation as a driver of disease progression in MDS", "abstract_text": "Hypomethylating agents (HMAs), including azacitidine and decitabine, are widely used for high-risk myelodysplastic syndromes (MDS) and selected AML, yet most patients eventually relapse, and survival after HMA failure remains dismal. HMAs were long assumed to function primarily by reactivating tumor suppressor genes through DNA demethylation. However, our recent work demonstrated that HMAs paradoxically upregulate the oncofetal gene SALL4, and that this induction strongly correlates with inferior overall survival, challenging existing paradigms. Emerging data suggest that additional cancer-germline antigen genes (CGAGs) may be similarly reactivated, generating oncogenic programs that facilitate resistance and leukemic progression. To investigate this, we profiled paired pre- and post-HMA patient marrow samples using RNA-seq and methylation analysis. We observed consistent post-treatment upregulation and promoter hypomethylation of SALL4 and multiple CGAGs, including PIWIL2, HORMAD1, and DDX43. Induction was more pronounced in patients with progression or treatment failure. Functional studies in MDS cell models revealed that forced expression of SALL4 or selected CGAGs enhanced proliferation, impaired myeloid differentiation, and reduced sensitivity to HMAs. Conversely, shRNA-mediated depletion mitigated these phenotypes. CRISPR-DiR-driven locus-specific demethylation of SALL4 recapitulated HMA-associated activation and conferred a proliferative advantage, confirming a causal role for promoter demethylation in SALL4 reactivation. We next evaluated therapeutic vulnerabilities associated with this pathway. Treatment with a newly developed small-molecule SALL4 degrader (SH6) reduced viability in SALL4-high models and reversed HMA-induced resistance phenotypes. Combination treatment with HMA + SH6 demonstrated enhanced cytotoxicity compared to either agent alone. Ongoing studies are expanding this approach to additional CGAG targets and mapping resistant subpopulations using single-cell transcriptomic and epigenetic profiling. Together, these findings reveal that HMA therapy can trigger unintended activation of oncogenic CGAG programs that drive MDS progression. They support a new mechanistic framework in which treatment-induced epigenetic reawakening promotes malignant fitness, and they identify SALL4 and CGAGs as high-value biomarkers and therapeutic targets. This work motivates development of companion diagnostic strategies and combination regimens pairing HMAs with targeted degraders to prevent therapy-induced disease acceleration and improve patient outcomes.", "source_company": "Brigham and Women's Hospital", "source_org_type": "医院", "row_number": 1066, "target_meta": "SALL4", "MOA_meta": "降解剂"}, {"drug_name": "neoantigen-specific TCR", "company": "University of Houston", "org_type": "大学", "target": "TP53 Y220C neoantigen (主要); NPM1 mutant neoantigen", "modality": "CAR", "importance_level": "中", "total_score": 55.8, "institution_score": 35, "track_score": 85, "milestone_score": 45, "field_heat_score": 75, "bonus_score": 3, "brief_reason": "针对AML中TP53 Y220C等复发性neoantigen的TCR设计管线，采用结构引导+深度学习+患者repertoire分析+安全性计算筛选，技术先进但仍处preclinical早期建模阶段。大学机构得分较低，neoantigen TCR赛道在实体瘤外扩展至AML热度较高，综合潜力中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3173", "id": "XFXM_5wBX1NQZOEH-LS6", "source_drug_name": "neoantigen-specific TCR", "title": "Neoantigen-guided TCR discovery pipeline to improve specificity and reduce off-target toxicity in AML", "abstract_text": "Identifying and engineering neoantigen-specific T cell receptors (TCRs) remains a major barrier to advancing adoptive immunotherapy for acute myeloid leukemia (AML), a malignancy characterized by a low mutational burden and, consequently, limited neoantigen availability. Recent studies have highlighted recurrent AML-associated mutations as promising sources of therapeutic neoantigens, arising from chromosomal alterations, motivating the development of new strategies to systematically discover and evaluate TCRs targeting antigens while minimizing off-target toxicity. We developed a structure-guided TCR discovery pipeline that designs neoantigen-specific TCRs, determines their presence within AML patient repertoires, and evaluates binding specificity and predicted safety. From the literature, we selected recurrent AML neoantigens restricted by HLA-A*02:01, including the TP53 Y220C peptide (VVPCEPPEV) and the NPM1 mutant peptide (AIQDLCVAV), both of which are among the most common TP53 hot-spot and the most frequent molecular alterations in AML. A melanoma-derived TCR-pHLA structure (PDB: 2BNQ) was used as an unbiased scaffold for inserting each AML neoantigen. ProteinMPNN, a deep learning-based protein sequence design, was then applied to redesign residues within CDR1-3, generating 50,000 candidate TCR sequences predicted to optimize interface complementarity and binding. Single-cell TCR-sequencing (scTCRseq) data were analyzed to extract paired α/β patient TCRs, with high-confidence receptors identified based on barcode redundancy and immune phenotype. Clustering of patient and designed TCRs using GLIPH2 revealed a dominant cluster comprising >90% of TP53-associated patient TCRs and two designed TCRs sharing a CDR3 motif, whereas no convergence was observed for NPM1 sequences. Three designed TCRs (two motif-convergent and one top-ranked by structural confidence) and the 62 patient TCRs from the convergent cluster were structurally modeled using TCRmodel2. All modeled TCRs are now being evaluated with STAG-LLM to predict binding specificity and interface similarity to the TP53-HLA complex. The top candidates will progress to molecular dynamics simulations to characterize contact fingerprints and evaluate potential off-target toxicity using CrossDome, which evaluates TCR cross-reactivity based on biochemical similarity between peptide-HLA ligands and predicts the off-target toxicity risk of T-cell-based immunotherapies. Initial results suggest structural and repertoire-based convergence toward recognition of TP53, supporting its relevance as an immunologic target for AML. By integrating rational TCR design, patient repertoire interrogation, and computational safety screening, this pipeline provides a scalable, reproducible framework for discovering neoantigen-specific, potentially low-toxicity TCR candidates for AML immunotherapy.", "source_company": "University of Houston", "source_org_type": "大学", "row_number": 76, "target_meta": "p53 Y220C,NPM1", "MOA_meta": "其他"}, {"drug_name": "allosteric SHP2 inhibitors", "company": "NYU Langone Health Perlmutter Cancer Center", "org_type": "医院", "target": "SHP2", "modality": "inhibitor", "importance_level": "中", "total_score": 55.8, "institution_score": 35, "track_score": 75, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "靶向SHP2的变构抑制剂，揭示pY62磷酸化作为原发性耐药机制并提出新靶点潜力。机构为医院学术型得分较低，但SHP2+MAPK通路在RAS驱动肿瘤中仍具较高赛道热度和一定机制创新加分。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1891", "id": "VVXM_5wBX1NQZOEH-LG5", "source_drug_name": "allosteric SHP2 inhibitors", "title": "A hotspot phosphorylation site on SHP2 drives oncoprotein activation and drug resistance", "abstract_text": "SHP2, a protein phosphatase encoded by PTPN11, is a critical mediator of receptor tyrosine kinase (RTK)-driven RAS/mitogen-activated protein kinase (MAPK) signaling and is targeted by allosteric inhibitors that stabilize its autoinhibited conformation. Despite promising preclinical data, SHP2 inhibitors have shown minimal clinical efficacy (monotherapy response rate ~0%), with no defined mechanisms of primary resistance in patients. Here, we elucidate phosphorylation of SHP2 at tyrosine 62 (pY62) as a hotspot phosphorylation site enriched across normal cells and tissues, cancer cells, and varied RTK-driven tumor types in patients. We demonstrate that SRC family kinases (SFKs) directly phosphorylate SHP2 at Y62, downstream but not directly phosphorylated by RTKs. Using biochemical and biophysical analyses, we show that SHP2 pY62 enforces an open, active conformation, resulting in constitutive phosphatase activation that is sufficient to activate MAPK signaling and confer resistance to allosteric SHP2 inhibitors. These findings establish SHP2 pY62 as a phosphorylation hotspot phenocopying mutational activation, as a mechanism of primary resistance to SHP2 inhibitors, and as a cancer drug target distinct from wildtype SHP2.", "source_company": "NYU Langone Health Perlmutter Cancer Center", "source_org_type": "医院", "row_number": 369, "target_meta": "SHP2", "MOA_meta": "抑制剂"}, {"drug_name": "CD33 TriKE", "company": "Washington University School of Medicine in St. Louis", "org_type": "大学", "target": "CD33", "modality": "TriKE", "importance_level": "中", "total_score": 55.8, "institution_score": 35, "track_score": 75, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "CD33 TriKE为三功能杀伤衔接剂（TriKE），通过靶向CD33并携IL-15增强memory-like NK细胞对AML的杀伤能力。大学机构分数较低，但TriKE平台+IL-15融合设计在NK细胞疗法领域有较好热度与创新性，体外体内数据扎实。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3684", "id": "e1XM_5wBX1NQZOEH-LG5", "source_drug_name": "CD33 TriKE", "title": "Memory-like NK cell targeting to CD123 and CD33 improves killing of acute myeloid leukemia", "abstract_text": "Background: Memory-like natural killer (ML NK) cells are NK cells which upon stimulation with IL12/15/18 undergo a differentiation process to develop improved metabolic fitness and enhanced killing capabilities of different types of malignant cells. They are a promising cellular therapeutic against acute myeloid leukemia (AML), for which the prognosis remains dismal for both pediatric and adult patients who experience relapse of their AML. Phase I studies of adoptive ML NK cell therapy in adult and pediatric patients showed promising results with several patients achieving complete responses, but many go on to relapse after a few months. We investigate two strategies to improve recognition of AML by memory like NK cells by targeting them to AML surface antigens CD33 and CD123.\nObjective: We target ML NK cells to CD123 by engineering ML NK cells to express a chimeric antigen receptor (CD123 CAR ML NK). We target ML NK cells to CD33 via a trispecific killer engager (CD33 TriKE) that enhances the immune synapse by engaging CD16 on the ML NK cell and CD33 on AML. The CD33 TriKE also contains IL-15 to enhance ML NK activation and survival. We also explore whether both technologies function synergistically to prevent immune escape.\nMethods: Treatment of AML with ML NK cells vs CD123 CAR ML NK cells, ML NK cells plus CD33 TriKE, or the combination, was compared in series of short and long-term assays. AML targets include MOLM13, THP-1, and Primary AML blasts. Interferon gamma production was assessed in a 6-hour co-incubation. In-vitro killing was assessed at 4-hours using a flow-based killing assay, and at 24 hours using a luciferase-based assay. Tumor control was assessed over 5 days using Incucyte (live cell imaging). Tumor control and survival in vivo was assessed using an THP-1 Xenograft model in NSG mice. Primary AML xenografts using NSG-S mice is under development. Results: Both targeting strategies demonstrate an antigen-specific killing response. Both strategies significantly increase interferon gamma production compared to ML NK cells (CAR vs MOLM13: +16.57%, p=0.0002, Primary AML #34: IFNg +9.1% p=0.0092; CD33 TriKE vs MOLM13: +24.42%, p=.0015, AML34: +9.1% p=0.0092). Both strategies also demonstrated increased AML killing at various E:T ratios (CAR vs MOLM13: p=.0011; AML34: p=.0006; CD33 TriKE vs MOLM13: p<.0001; AML34 p=.0026). Both CD123 CAR and CD33 TriKE improved THP-1 control in vivo (bioluminescence at 23 days-CD123 CAR: p=0.004, CD33 TriKE: p<.0001). Both therapies improved median survival by about 3 weeks (CD123 CAR: p<.0001, CD33 TriKE: p=.0001).\nConclusion: CD123 CAR ML NK cells and ML NK cells treated with CD33 TriKE both enhance the abilities of ML NK cells to kill AML in vitro and in vivo, and prolong time of survival of THP-1 bearing mice. Treatment of CD123 CAR ML NK cells with CD33 TriKE may prevent antigen escape. Either of these targeting strategies are highly translatable to the clinical setting.", "source_company": "Washington University School of Medicine in St. Louis", "source_org_type": "大学", "row_number": 392, "target_meta": "CD33", "MOA_meta": "其他"}, {"drug_name": "anti-CTLA-4", "company": "UT MD Anderson Cancer Center", "org_type": "医院", "target": "CTLA-4", "modality": "inhibitor", "importance_level": "中", "total_score": 55.8, "institution_score": 35, "track_score": 75, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "药物为anti-CTLA-4抑制剂，靶向CTLA-4，与Alpha DaRT联合在mtKRAS PDAC模型中显示协同效应及局部/系统性抗肿瘤免疫。机构为医院学术型得低分，赛道为经典ICI+创新放疗组合热度较高，preclinical强效协同及免疫记忆获一定认可，总分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3955", "id": "GlXM_5wBX1NQZOEH-LO6", "source_drug_name": "anti-CTLA-4", "title": "Alpha-particle radiotherapy combined with anti-CTLA-4 synergistically overcomes radioresistance and induces local and systemic antitumor immunity in PDAC", "abstract_text": "Pancreatic ductal adenocarcinoma (PDAC) is the third leading cause of cancer death in the U.S., with over 90% of patients presenting mutant KRAS (mtKRAS). Increased radioresistance and elevated CTLA-4 expression are hallmarks driven by mtKRAS. Radiation has only shown meaningful efficacy in PDAC at very high doses that are not achievable with conventional radiotherapy due to toxicity to adjacent organs. Additionally, although CTLA-4 upregulation suggests a therapeutic target, PDAC shows limited response to immune checkpoint blockade because of its highly immunosuppressive tumor microenvironment. We propose to sensitize a cold mtKRAS murine PDAC model (KPC) to anti-CTLA-4 (aCTLA-4) by overcoming radioresistance using Diffusing Alpha-emitters Radiation Therapy (Alpha DaRT), an intratumoral source of alpha particles with >1,000-fold greater ionization density than photons. This enables delivery of very high doses directly to the tumor while sparing healthy tissue. To further enhance this effect, an ATR inhibitor will impair DNA repair, increasing susceptibility to treatment. To assess local tumor response, mice received 5×10⁵ cells in the left leg, and after 7 days (day 0) one DaRT source (inert or active) was implanted. ATRi (75 mg/kg) or DMSO was administered orally on days 0, 1, 2, 7, 8, and 9, and aCTLA-4 or IgG was injected intraperitoneally every 3 days starting on day 3 (4 doses). Animals with complete regression (>100 days tumor-free) were rechallenged on day 130. To assess systemic immunity, mice received 5×10⁵ KPC cells in the left leg and 1×10⁵ in the right leg, and after 10 days (day 0) one DaRT source was implanted in the left leg. The drug schedule was identical, except mice received six doses of aCTLA-4. The triple therapy (Alpha DaRT + ATRi + aCTLA-4) induced significantly (p<0.05) greater tumor growth delay compared to control, monotherapies, and duotherapies, excluding Alpha DaRT + aCTLA-4, from day 25 onward. By day 41, all control and monotherapy mice reached euthanasia criteria, whereas 60% and 70% of the Alpha DaRT + aCTLA-4 and triple therapy groups remained alive. Complete tumor regression >100 days was sustained in 40% and 50% of mice, respectively. Upon rechallenge, no tumors regrew in the Alpha DaRT + aCTLA-4 group, and only 1 of 5 in the triple therapy group showed regrowth. A significant (p<0.0001) synergistic effect was observed between Alpha DaRT and aCTLA-4. For systemic immunity, Alpha DaRT + aCTLA-4 and the triple therapy induced greater tumor growth delay in both the irradiated and unirradiated tumors compared to all other treatments. In conclusion, Alpha DaRT combined with aCTLA-4 generates durable local and systemic antitumor responses in mtKRAS PDAC, offering a strategy to overcome KRAS-mediated radioresistance and immune evasion.", "source_company": "UT MD Anderson Cancer Center", "source_org_type": "医院", "row_number": 666, "target_meta": "CTLA4", "MOA_meta": "抑制剂"}, {"drug_name": "anti-PD-1", "company": "MD Anderson Cancer Center", "org_type": "医院", "target": "PD-1", "modality": "inhibitor", "importance_level": "中", "total_score": 55.8, "institution_score": 35, "track_score": 75, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "anti-PD-1为经典免疫检查点抑制剂，TTFields联合可逆转其耐药性并显著提升疗效。机构为顶级肿瘤医院但非药企，preclinical模型中显示肿瘤消退及生存获益，赛道仍具较高热度。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5589", "id": "91XM_5wBX1NQZOEH-LO6", "source_drug_name": "anti-PD-1", "title": "Tumor treating fields (TTFields) overcome anti-PD-1 resistance in a murine lung adenocarcinoma model", "abstract_text": "Tumor Treating Fields (TTFields) are low-intensity, intermediate-frequency alternating electric fields that disrupt mitosis and elicit immunogenic stress. Although TTFields are clinically approved for metastatic non-small-cell lung cancer (mNSCLC) with PD-1/PD-L1 inhibitors or docetaxel, their mechanistic synergy in anti-PD-1-resistant disease remains incompletely understood. We investigated the temporal transcriptomic and functional impact of TTFields using the murine 344SQR lung adenocarcinoma model, which is intrinsically resistant to PD-1 blockade.344SQR cells were exposed to TTFields (150 kHz, 1.62 V/cm) for 24-72 h using the inovitro™ system, and proliferation and clonogenic survival were quantified. RNA-seq with Gene Set Enrichment Analysis (GSEA) defined pathway modulation at 48 h and 72 h. In vivo, 129Sv/Ev mice bearing 344SQR tumors were treated with the inovivo™ system, anti-PD-1, or both treatments together.TTFields significantly inhibited 344SQR proliferation (~60 % reduction at 72 h) and clonogenic survival in vitro. GSEA revealed dynamic, stage-specific transcriptional remodeling. At 48 h, TTFields downregulated mitotic-spindle, DNA-replication, and epithelial-mesenchymal-transition gene sets, indicating early mitotic arrest and replication stress. By 72 h, cells exhibited re-enrichment of G2M-checkpoint, E2F, MYC, and mitotic-spindle programs together with activation of peroxisomal and xenobiotic-metabolism pathways, consistent with sustained mitotic stress and oxidative-damage adaptation. In contrast, marked suppression of glycosyltransferase activity suggested impaired membrane and secretory functions, signifying progression toward metabolic exhaustion and immunogenic cell death.In vivo, TTFields monotherapy delayed tumor progression, while concurrent treatment with TTFields and anti-PD-1 produced significant tumor regression and extended median survival (32 days vs 20-21 days for control or monotherapies). Single-cell transcriptomics revealed that TTFields plus anti-PD-1 increased infiltration of CD8⁺ cytotoxic T cells and B cells while reducing regulatory T cells, shifting the tumor microenvironment toward an effector-dominant state.These findings demonstrate that TTFields trigger sequential mitotic stress and metabolic collapse, generating an immunogenic tumor phenotype that restores responsiveness to PD-1 blockade. Sustained tumor control requires PD-1 inhibition to capitalize on TTFields-induced immunogenic remodeling and prevent regrowth of metabolically adapted residual cells.", "source_company": "MD Anderson Cancer Center", "source_org_type": "医院", "row_number": 824, "target_meta": "PD1", "MOA_meta": "抑制剂"}, {"drug_name": "Prussian Blue nanoparticle-photothermal therapy (PBNP-PTT)-engineered T cells", "company": "George Washington University Cancer Center", "org_type": "研究机构", "target": "未披露", "modality": "other", "importance_level": "中", "total_score": 55.5, "institution_score": 35, "track_score": 75, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "采用PBNP-PTT新型方法ex vivo工程化T细胞增强卵巢癌特异性免疫应答，机制新颖但靶点未明确披露。机构为大学癌症中心非产业化主体得低分，赛道结合细胞治疗+纳米光热有一定热度，preclinical体内显著疗效及人源验证构成中等重要性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4556", "id": "LVXM_5wBX1NQZOEH-LS6", "source_drug_name": "Prussian Blue nanoparticle-photothermal therapy (PBNP-PTT)-engineered T cells", "title": "Antigen-specific T cells engineered with nanoparticle photothermal therapy demonstrate antitumor efficacy in an immunocompetent murine model of ovarian cancer", "abstract_text": "Ovarian cancer (OC) is the most lethal gynecological malignancy with less than a 10% response rate to immune checkpoint blockade. Personalized vaccination with tumor lysate-pulsed dendritic cells amplifies T cell responses, including neoepitope-specific T cells, but is not curative. Thus, amplifying the pre-existing tumor-specific T cell response is insufficient. We developed a novel method to expand T cells ex vivo for OC specificity using Prussian Blue nanoparticle-photothermal therapy (PBNP-PTT), and verified in vivo efficacy using a syngeneic murine model. PBNP-PTT -generated ID8 OC cell lysate was used to stimulate bone marrow-derived dendritic cells (BMDCs) isolated from healthy female C57Bl6 mice. Autologous splenic CD3+ T cells were cocultured ex vivo with BMDCs and assessed in vitro for tumor-specific activation and killing using IFNy ELISpot and MTS cytotoxicity assays. Congenic mice bearing ID8B OC cells received either ex vivo expanded T cells or nonspecifically expanded T cells, and the accumulated ascites was profiled for cytokine composition. Adoptively transferred T cells were immunophenotyped with spectral flow cytometry.Ex vivo expansion of T cells with DCs primed using PBNP-PTT-generated OC cell lysate produced a pool of CD8+ T cells with enhanced IFNy and TNFa secretion in tumor coculture compared to nonspecifically expanded T cells. PBNP-PTT-expanded T cells exhibited greater tumor cell killing at increasing effector-to-target ratios and did not demonstrate off-target IFNy secretion. Tumor-bearing female C57Bl6 mice receiving OC-expanded T cells lived significantly longer and exhibited decreased tumor burden compared to mice receiving nonspecific T cells. Adoptively transferred T cells expanded with PBNP-PTT lysate also persisted longer in vivo with maintained activation in the ascites, and synergized with concurrent epigenetic therapy to further prolong survival. Ex vivo expansion methods using PBNP-PTT were also applied to healthy human blood donors to generate human T cells that demonstrate potent activation when challenged with human OC cell lines. In summary, we developed a novel method of engineering T cells ex vivo for specificity against ovarian cancer using nanoparticle photothermal therapy. This study is the first to harness PBNP-PTT ex vivo to demonstrate antitumor activity in vivo using an autologous mouse model of ovarian cancer.", "source_company": "George Washington University Cancer Center", "source_org_type": "研究机构", "row_number": 72, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "HD-11273", "company": "Hyundai pharmaceutics", "org_type": "公司", "target": "SMARCA2", "modality": "inhibitor", "importance_level": "中", "total_score": 55.5, "institution_score": 45, "track_score": 75, "milestone_score": 45, "field_heat_score": 70, "bonus_score": 2, "brief_reason": "HD-11273为选择性SMARCA2抑制剂，针对SMARCA4缺陷癌尤其是NSCLC中的合成致死靶点，赛道具有较高热度但非最热门。机构为韩国中型传统药企而非头部创新biotech，处于preclinical阶段仅显示模型中单药及联合协同效应，综合潜力中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4031", "id": "uFXM_5wBX1NQZOEH-LO6", "source_drug_name": "HD-11273", "title": "Combination therapy with selective SMARCA2 (BRM) inhibitor HD-11273 for treatment of SMARCA4 (BRG1)-deficient cancers", "abstract_text": "SMARCA2 (BRM) and SMARCA4 (BRG1) are the catalytic subunits of SWI/SNF chromatin remodeling complexes, functioning in a mutually exclusive manner to regulate nucleosome composition via their ATPase domains. Pan-cancer analysis indicates that SMARCA4 mutations occur at all cancers, in particular, SMARCA4 mutations are found in 8-10% of non-small cell lung cancer (NSCLC) cases, suggesting SMARCA2 as a potential synthetic lethal target. Several studies reported that the co-mutation frequency of KRAS and SMARCA4 in NSCLC is approximately 7.7-10%, with about 39-47% of these SMARCA4-mutant patients harboring KRAS mutations. And patients with SMARCA4-mutant NSCLC generally demonstrate poor responses to conventional chemotherapy. We selected HD-11273 as a preclinical candidate, which showed improved physicochemical properties through the preparation of a specific salt of HD-10991, a selective SMARCA2 inhibitor. Here, we report a combination study of HD-11273 with standard chemotherapy and KRAS inhibitors currently in development. HD-11273 monotherapy significantly inhibited growth of SMARCA4-del A549 CDX model as well as patient derived cancer organoid (PDO) models. Combination therapies targeting multiple pathways are considered essential for overcoming monotherapy limitations, including resistance arising from prolonged treatment. To evaluate the therapeutic benefit, we tested our selective SMARCA2 inhibitor in combination with KRASG12C (storasib, adagrasib), KRASG12D (RMC9805), and pan-KRAS (Draxonrasib) inhibitors in cancers harboring KRAS and SMARCA4 co-mutations. Each combination exhibited robust synergy, suggesting that dual targeting of SMARCA2 and KRAS could be a promising therapeutic strategy. Additionally, we investigated the combinatory effect of a SMARCA2 inhibitor with standard chemotherapy agents for NSCLC; combination with oxaliplatin, docetaxel, or pemetrexed showed partial synergy, indicating that SMARCA2 inhibitors may serve as promising candidates for combination chemotherapy. In conclusion, the combination of HD-11273 with KRAS targeted therapy showed synergistic anti-tumor effect in preclinical models of SMARCA4 and KRAS co-mutated NSCLC. Also, the combination of HD-11273 with standard care for NSCLC chemotherapy significantly enhances anti-tumor activity in preclinical models of SMARCA4-mutated NSCLC.", "source_company": "Hyundai pharmaceutics", "source_org_type": "公司", "row_number": 156, "target_meta": "SMARCA2", "MOA_meta": "抑制剂"}, {"drug_name": "3H9-KGDEVD-MMAE", "company": "Seoul National University", "org_type": "大学", "target": "PRND", "modality": "ADC", "importance_level": "中", "total_score": 55.5, "institution_score": 35, "track_score": 75, "milestone_score": 70, "field_heat_score": 65, "bonus_score": 5, "brief_reason": "靶向PRND（Doppel）的ADC，通过双重cathepsin B/caspase激活实现血管靶向+旁观者效应和反馈放大，针对胶质母细胞瘤等高血管肿瘤显示强效回归。大学机构分数较低，但ADC赛道+新型血管破坏机制+preclinical强效数据综合热度中等偏上。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4035", "id": "ulXM_5wBX1NQZOEH-LG6", "source_drug_name": "3H9-KGDEVD-MMAE", "title": "Tumor endothelial cell and cancer cell targeting anti-PRND antibody-drug conjugate to treat hypervascular tumors such as glioblastoma and sarcomas", "abstract_text": "Antibody-drug conjugates (ADCs) have emerged as a major class of targeted therapeutics but remain limited by poor tumor penetration, antigen heterogeneity, and a narrow therapeutic window. To overcome these limitations, we developed an anti-PRND ADC targeting PRND (Doppel), a prion-like glycoprotein selectively expressed in tumor endothelial cells (TECs) and cancer cells but absent in normal tissues except in the testis. This localization enables direct vascular targeting without diffusion barriers and provides a unique opportunity for precise drug delivery to the tumor vasculature. The resulting antibody-drug conjugate, 3H9-KGDEVD-MMAE, is a homogeneous ADC (DAR = 8) free of soluble aggregates. It couples a high-affinity anti-PRND antibody (3H9) with a caspase/cathepsin B-cleavable KGDEVD linker that can be specifically cleaved by both cathepsin B and caspase-3/7. This dual activation allows MMAE release through lysosomal cathepsin B and induces apoptosis of PRND positive cells, and caspase-3/7 from the apoptosis of target cells induces the apoptosis of adjacent tumor tissues. The caspase-mediated cleavage establishes an in-situ feedback amplification loop that maintains continuous local drug release, sustained cytotoxicity, and producing a potent bystander effect that overcomes antigen heterogeneity. By combining TEC and cancer cell-specific targeting with a caspase/cathepsin-responsive linker, 3H9-KGDEVD-MMAE (anti-PRND ADC), achieves deep intratumoral penetration, robust vascular disruption, and durable antitumor efficacy. In preclinical models of glioblastoma, sarcoma, and renal cell carcinoma (RCC) - hypervascular malignancies with limited ADC options, anti-PRND ADC induced extensive and durable tumor regressions without systemic toxicity. Collectively, these findings establish anti-PRND ADC as a next-generation vascular-disrupting ADC, integrating endothelial docking with apoptosis-triggered drug amplification for potent and selective control of highly vascularized tumors.\nAcknowledgments: This research was supported by the Korea Drug Development Fund (HN21C0264) funded by the Ministry of Science and ICT and the National Research Foundation of Korea (NRF) grant (2020R1A2C2015026) funded by the Korea government (MSIT).", "source_company": "Seoul National University", "source_org_type": "大学", "row_number": 196, "target_meta": "PRND", "MOA_meta": "抗体偶联药物"}, {"drug_name": "pH responsive antibodies", "company": "Changping Laboratory", "org_type": "研究机构", "target": "未披露", "modality": "antibody", "importance_level": "中", "total_score": 55.5, "institution_score": 45, "track_score": 85, "milestone_score": 35, "field_heat_score": 70, "bonus_score": 5, "brief_reason": "药物为pH响应型抗体，利用肿瘤酸性微环境实现选择性靶向，提高治疗指数，但摘要被禁未披露具体靶点和机制细节。机构为研究机构非头部药企得较低分，赛道为热门pH敏感抗体创新机制获高分，但仅标题信息无明确开发阶段里程碑。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11301", "id": "8FXM_5wBX1NQZOEH-LC5", "source_drug_name": "pH responsive antibodies", "title": "AI guided engineering of pH responsive antibodies enables tumor selective targeting and improves the therapeutic index", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Changping Laboratory", "source_org_type": "研究机构", "row_number": 297, "target_meta": "not available", "MOA_meta": "抗体"}, {"drug_name": "CD19 CAR T-cell therapy", "company": "Mayo Clinic", "org_type": "医院", "target": "CD19", "modality": "CAR", "importance_level": "中", "total_score": 55.5, "institution_score": 35, "track_score": 85, "milestone_score": 50, "field_heat_score": 75, "bonus_score": 0, "brief_reason": "靶向CD19的CAR-T细胞疗法，研究揭示代谢通路（OXPHOS、糖酵解等）与疗效持久性的关联。Mayo Clinic作为顶级学术医院机构分较低，但CAR-T赛道及B-NHL领域热度高，基于商业化产品真实世界数据的代谢生物标志物分析具有一定价值。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9186", "id": "BVXM_5wBX1NQZOEH-LG5", "source_drug_name": "CD19 CAR T-cell therapy", "title": "Metabolic pathway signatures defining response to CD19 CAR T-Cell therapy in aggressive B-cell non-hodgkin lymphoma", "abstract_text": "Chimeric antigen receptor (CAR) T-cell therapy achieves high response rates in relapsed/refractory aggressive B-cell non-Hodgkin lymphoma, yet only 40% of patients achieve durable remission. Identifying biological programs linked to long-term response remains critical. As metabolic fitness underlies T-cell persistence and effector function, we profiled metabolic pathways associated with clinical outcomes following commercial CD19 CAR T-cell therapy.\nSingle-cell RNA sequencing of peripheral blood mononuclear cells collected at baseline (BL), peak CAR-T expansion (PK), and one-month post-infusion (M1) was analyzed using CellRanger v7.0.1, immunopipe. Seurat v4.3.0 was applied for unsupervised clustering to delineate cell subsets based on top differentially expressed genes. Patients were categorized as durable complete remission (CR ≥6 months; n = 16), primary refractory (PD1; n = 4), or relapse after initial response (PD2; n = 12). Gene-set enrichment analysis defined metabolic pathway activity across T-cell, monocyte, dendritic cell (DC), and natural killer (NK) subsets.\nOxidative phosphorylation (OXPHOS) emerged as the dominant metabolic program distinguishing clinical outcomes. At BL and PK, OXPHOS was consistently enriched in PD1 relative to CR across T-cell, monocyte, and DC subsets, suggesting early oxidative activation in non-responders. By M1, this pattern inverted, with higher OXPHOS activity in CR. PD2 largely paralleled PD1, but several subsets including CD8 T central memory, classical monocytes TGFβ, intermediate monocytes CD38, monocytic myeloid-derived suppressor cell (mMDSC) HIF1A, and mMDSC SIRPA, showed OXPHOS enrichment in CR at BL and/or PK that persisted through M1. In contrast, DC and NK subsets exhibited the opposite pattern: OXPHOS was enriched in CR at PK (conventional DC 2 (cDC2), plasmacytoid DC (pDC), NK, proliferating NK), but shifted toward enrichment in PD2 at M1 (cDC2, NK, NK CD56bright).\nGlycolysis (GLY) followed a similar trajectory in monocytes and NK cells, with enrichment in PD1/PD2 at BL and PK, followed by enrichment in CR at M1. In T-cells, PD1 maintained GLY enrichment from BL through PK, with no significant differences observed at M1.\nThe inositol-phosphate metabolism pathway showed a more static pattern and was consistently enriched in multiple PD2 effector and memory T-cell subsets without reversal at M1.\nTaken together, these data reveal distinct, lineage-specific metabolic signatures that differentiate durable remission from early and late progression. Dynamic OXPHOS and GLY programming, characterized by lower activity early and enhanced activity at M1 in CR, may reflect adaptive metabolic programming that supports sustained antitumor immunity. Immune-metabolic profiling may therefore serve as a biomarker of response and highlight actionable metabolic pathways to enhance CAR T-cell durability.", "source_company": "Mayo Clinic\nMayo clinic", "source_org_type": "医院", "row_number": 315, "target_meta": "CD19", "MOA_meta": "其他"}, {"drug_name": "FDA-approved HER2-targeting ADCs", "company": "HUB Organoids B.V.", "org_type": "公司", "target": "HER2", "modality": "ADC", "importance_level": "中", "total_score": 55.5, "institution_score": 45, "track_score": 90, "milestone_score": 35, "field_heat_score": 75, "bonus_score": 0, "brief_reason": "药品为已获FDA批准的HER2靶向ADC，ADC赛道和HER2靶点均属高热度领域。HUB Organoids为专注患者来源类器官的生物技术公司，非头部药企，主要开展方法学研究而非新药开发，整体临床里程碑价值有限。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3519", "id": "N1XM_5wBX1NQZOEH-LG5", "source_drug_name": "FDA-approved HER2-targeting ADCs", "title": "An image-based approach to visualize ADC internalization and cytotoxicity in patient-derived organoids", "abstract_text": "Antibody-drug conjugates (ADCs) represent an emerging class of cancer therapies designed to address the limitations of traditional chemotherapy, particularly the toxicity that arises from healthy cells being exposed to cytotoxic agents. ADCs combine a target-specific monoclonal antibody with a cytotoxic payload, enabling selective delivery to cancer cells and significantly reducing adverse effects. HUB Patient-Derived Organoids (PDOs) are advanced 3D in vitro models derived from adult stem cells that faithfully replicate the architecture, genetics, and physiology of original patient tissues. By preserving patient-specific genetic and phenotypic traits, including surface marker expression, HUB has established a comprehensive and well-characterized biobank of tumor-derived PDOs. This biobank provides a powerful platform for translational research, drug discovery, and the development of targeted therapies. In this study, we present an organoid-based, image-based internalization assay that complements standard Cell Titer-Glo viability assays by enabling direct visualization of ADC internalization. This assay facilitates a deeper exploration of the mechanisms of action of ADCs. We pre-selected tumor-derived organoids based on HER2 expression, which was assessed using flow cytometry. After treating the organoids with FDA-approved HER2-targeting ADCs, we utilized the internalization assay to support the viability data and to define key parameters such as the timing of action, the effect of the payload, and whether cell death resulted from ADC internalization. Overall, these results reinforce the value of patient-derived organoids as a physiologically relevant preclinical platform for ADC development. They also highlight the suitability of the described image-based assay for investigating critical stages of ADC mechanisms, including internalization and payload activity.", "source_company": "HUB Organoids B.V.", "source_org_type": "公司", "row_number": 345, "target_meta": "HER2", "MOA_meta": "抗体偶联药物"}, {"drug_name": "bimodal Spherical Nucleic Acid (bi-SNA)", "company": "Washington University in St. Louis", "org_type": "大学", "target": "cGAS / STAT3", "modality": "other", "importance_level": "中", "total_score": 55.5, "institution_score": 35, "track_score": 75, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 4, "brief_reason": "bi-SNA通过金核搭载STAT3 decoy序列实现cGAS激活+STAT3抑制，双机制重编程GBM免疫微环境；大学机构+非热门modality但脑递送+免疫调节策略有一定创新，preclinical模型显示显著疗效和脑靶向优势。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6407", "id": "V1XM_5wBX1NQZOEH-LG5", "source_drug_name": "bimodal Spherical Nucleic Acid (bi-SNA)", "title": "Harnessing facial neuronal pathways via iontophoresis for targeted intradermal delivery of bimodal spherical nucleic acids to the brain for anti-glioma  effect", "abstract_text": "Background: Glioblastoma (GBM) remains one of the most aggressive brain tumors due to barriers in drug delivery across the blood-brain barrier (BBB) and its profoundly immunosuppressive tumor microenvironment (TME). These limitations restrict therapeutic penetration into tumor sites. While intranasal strategies exploit trigeminal/olfactory routes, mucociliary clearance and off-target exposure have limited clinical translation. Here, we developed a facial dermal iontophoresis-based system to deliver immune-modulating nanoparticles through the facial neuro-lymphatic network to bypass the BBB and reprogram the TME.\nMethods: To overcome delivery barriers affecting immunotherapies intended to modulate tumor-associated and peripheral immunity, we integrated two approaches. First, we established iontophoresis as a minimally invasive method to bypass the BBB and enhance the transport of therapeutics delivered via facial intradermal (i.d.) injection. Second, we engineered a bimodal Spherical Nucleic Acid (bi-SNA) platform that activates cGAS and inhibits STAT3. Bi-SNAs consist of a 15-nm gold core functionalized with a hairpin oligonucleotide with STAT3-decoy sequences, enabling simultaneous cGAS activation and STAT3 sequestration. Bi-SNAs elicit potent antitumor immunity in multiple HGG models and outperform cGAS-agonist monotherapies. A dedicated iontophoresis device was designed for preclinical assessment using murine GBM models, and iontophoretic parameters (current density, waveform, electrode placement) were optimized for controlled transdermal SNA transport. Biodistribution was measured by 3D fluorescence CT-IVIS with ICG-labeled SNAs, gold levels by ICP-MS, and immune modulation by multispectral flow cytometry.\nResults: I.d. Bi-SNA delivery with iontophoresis significantly suppressed tumor progression, depleted immunosuppressive myeloid cells, and increased recruitment/activation of effector T cells. IVIS imaging showed a two-fold increase and faster kinetics of SNA trafficking from facial planes to the brain without detectable systemic spread, with preferential accumulation along maxillary-olfactory and temporomandibular conduits. ICP-MS revealed ~20-fold higher gold deposition in the brain and trigeminal nerve within 12 hours compared with passive i.d. delivery.\nConclusions: Iontophoresis-enhanced i.d. delivery provides a powerful non-invasive strategy for brain-targeted immunotherapy, leveraging neuronal pathways to bypass the BBB and reprogram the GBM TME. This establishes a foundation for patient-adaptable, at-home nanotherapeutic delivery for brain tumors.", "source_company": "Washington University in St. Louis", "source_org_type": "大学", "row_number": 373, "target_meta": "cGAS,STAT3", "MOA_meta": "其他"}, {"drug_name": "Nanobody:STING agonists", "company": "Vanderbilt University", "org_type": "大学", "target": "STING", "modality": "nanobody", "importance_level": "中", "total_score": 55.5, "institution_score": 35, "track_score": 85, "milestone_score": 60, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "该Nanobody偶联STING激动剂通过 hitchhiking 机制改善递送并重编程肿瘤微环境，提升固体瘤过继细胞治疗效果，但靶点为STING激动剂而非直接靶向肿瘤抗原。机构为大学学术型，得分较低，但STING通路+nanobody递送平台在免疫治疗赛道热度高，前临床数据显示改善ACT疗效及肿瘤抑制，具有一定潜力。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11385", "id": "nFXM_5wBX1NQZOEH-LG6", "source_drug_name": "Nanobody:STING agonists", "title": "Nanobody:STING agonists reprogram the tumor microenvironment and improve adoptive cell therapy for solid tumors", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Vanderbilt University", "source_org_type": "大学", "row_number": 418, "target_meta": "STING", "MOA_meta": "单域抗体"}, {"drug_name": "QW-5-70", "company": "University of Tennessee Health Science Center", "org_type": "大学", "target": "colchicine site (tubulin)", "modality": "inhibitor", "importance_level": "中", "total_score": 55.5, "institution_score": 35, "track_score": 65, "milestone_score": 75, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "QW-5-70为新型colchicine位点抑制剂，通过规避P-gp外排显著克服多药耐药，在耐药神经母细胞瘤和前列腺癌模型中展现体内外强效抗肿瘤活性。大学机构得分较低，但preclinical数据扎实且具耐药突破亮点，赛道为微管靶向抑制剂中等热度，总分中等偏上。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4891", "id": "v1XM_5wBX1NQZOEH-LG6", "source_drug_name": "QW-5-70", "title": "QW-5-70 targets the colchicine site to overcome multidrug resistance and shows potent antitumor activities", "abstract_text": "Drug resistance driven by efflux transporters and altered tubulin dynamics limits the clinical efficacy of taxanes and vincristine in high-risk neuroblastoma (NB) and castration-resistant prostate cancer (CRPC). We developed QW-5-70, a colchicine-binding-site inhibitor (CBSI), engineered to retain subnanomolar potency in both parental and drug-resistant cancer cells by evading P-glycoprotein (P-gp)-mediated efflux. QW-5-70 binds to the colchicine site, inhibits tubulin polymerization, disrupts microtubule networks, and induces mitotic arrest. Across a panel of NB and prostate cancer lines, QW-5-70 maintained subnanomolar activity and remained effective in vincristine-resistant BE2C/VCR and paclitaxel-resistant PC-3/TxR cells. Unlike vincristine and paclitaxel, its activity was unchanged by co-treatment with verapamil, suggesting its ability to circumvent P-gp-mediated drug resistance. In vitro, QW-5-70 significantly reduced colony formation and impaired migration in both parental and resistant cancer cells, and induced G2/M cell cycle arrest and mitochondrial apoptosis. In vivo, QW-5-70 significantly suppressed tumor growth in drug-resistant PC-3/TxR and BE2C/VCR xenografts, with modest weight loss and no evident histopathology in the major organs. Combination testing revealed strong quantitative synergy with DFMO in viability assays and marked increases in apoptosis with reduced clonogenic survival when paired with DFMO or the Aurora A inhibitor MLN8237. Collectively, QW-5-70 is a potent CBSI that circumvents P-gp-associated resistance, triggers mitotic arrest and apoptosis, and achieves robust antitumor activity in multidrug-resistant tumor models with acceptable tolerability, supporting its further preclinical development alone and in combination with other drugs.", "source_company": "University of Tennessee Health Science Center", "source_org_type": "大学", "row_number": 445, "target_meta": "microtubule", "MOA_meta": "抑制剂"}, {"drug_name": "arecoline hydrobromide", "company": "CONICET-Universidad de Buenos Aires, University of Buenos Aires", "org_type": "研究机构/大学", "target": "ACAT1", "modality": "inhibitor", "importance_level": "中", "total_score": 55.5, "institution_score": 35, "track_score": 65, "milestone_score": 75, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "Arecoline hydrobromide为ACAT1抑制剂，靶向酮体代谢关键酶ACAT1，在CRPC及骨转移前列腺癌模型中显示显著抑瘤活性。机构为阿根廷大学/研究机构得分较低，但preclinical数据较扎实包括PDX模型体内疗效，代谢靶点在前列腺癌领域有一定新颖性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9172", "id": "x1XM_5wBX1NQZOEH-LG6", "source_drug_name": "arecoline hydrobromide", "title": "Exploiting ketone body metabolism as a therapeutic vulnerability in prostate cancer", "abstract_text": "Prostate cancer (PCa) progression remains a major clinical challenge with limited therapeutic options, and the complexity of metabolic pathways fueling advanced PCa rests poorly understood. We have identified a shift from glycolysis to ketone body (KB) metabolism in castration-resistant PCa (CRPC), with an upregulation of ketolytic/ketogenic enzymes. From these, ACAT1 is a potential therapeutic candidate, as its expression is elevated in aggressive PCa and associates with unfavorable clinical outcomes. Here, we investigated the contribution of the bone niche -the dominant PCa metastatic site- to KB metabolism during PCa progression and evaluated ACAT1 inhibition as a treatment strategy for advanced disease. Co-culture experiments between PCa cells and bone progenitors (MC3T3, Raw264.7) were used to evaluate bone-driven metabolic adaptations. To validate in vivo the effect of the bone niche, we implanted MDA PCa patient-derived xenograft (PDX) 183 either intrafemorally (i.f.) or subcutaneously (s.c.) in sham or castrated CB17 SCID mice. We assessed cell viability in PCa cells lines and in PDX-derived organoids (PDX.DO), treated with increasing concentrations of ACAT1 inhibitor, arecoline hydrobromide (AH). ACAT1 and phospho-ACAT1 levels were measured by Western blot and immunofluorescence. Intracellular KB and ATP content were quantified by luciferase-based assays. Lipid uptake and accumulation were quantified by flow cytometry using Bodipy probes. In vivo, mice bearing MDA PCa PDXs 183, 203 and 173 were treated with AH (50 mg/kg/day i.p., 21 days). Tumor volume, KB content, and ACAT1 modulation were evaluated. We observed transcriptional activation of lipid and KB metabolism in PC3 cells from PCa-bone co-cultures, and consistently, in i.f. PDXs compared to matched s.c. tumors, alongside a significant increase in ACAT1 expression levels. Castration dynamically modulated ACAT1 levels in MDA PCa 183 tumors growing i.f., with initial downregulation followed by restoration over time, underscoring KB metabolism as a mechanism of resistance within the bone niche. Functional studies showed that AH treatment reduced cell viability in PC3, C42B, and 22Rv1 cells, as well as PDX.DO, decreased ACAT1 and phospho-ACAT1 expression, lowered KB levels, and altered lipid dynamics by increasing lipid accumulation, uptake, and decreasing ATP content (P<0.05). In vivo, AH treatment in MDA PCa 183 tumors led to a significant reduction in tumor volume and intratumoral KB content (P<0.05). Moreover, in the CRPC model MDA PCa 203 -derived from a longitudinal sample of the same patient as 183-, and in the aggressive hormone-naïve model MDA PCa 173, AH treatment significantly reduced both tumor volume and KB content (P<0.05). In conclusion, our findings reveal KB metabolism as a critical vulnerability in PCa progression, with ACAT1 emerging as a druggable target whose inhibition disrupts tumor growth and metabolic fitness.", "source_company": "CONICET-Universidad de Buenos Aires\nUniversity of Buenos Aires", "source_org_type": "研究机构\n大学", "row_number": 452, "target_meta": "ACAT1,SOAT1", "MOA_meta": "抑制剂"}, {"drug_name": "ONIOYID", "company": "Mayo Clinic", "org_type": "医院", "target": "未披露", "modality": "other", "importance_level": "中", "total_score": 55.5, "institution_score": 35, "track_score": 70, "milestone_score": 75, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "ONIOYID为 investigational anti-tumor agent，摘要未明确披露具体靶点或作用机制，仅描述其与pan-KRAS抑制剂联用在PDAC模型中显示协同抗瘤、逆转纤维化和增强T细胞浸润的显著效果。Mayo Clinic作为顶级医院机构有一定研究实力，preclinical数据强劲（>90%肿瘤消退+生存改善），PDAC领域高未满足需求，但机构非药企且靶点/ modality 未明导致总分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5739", "id": "4lXM_5wBX1NQZOEH-LG6", "source_drug_name": "ONIOYID", "title": "Combined KRAS pathway inhibition and ONIOYID treatment enhances tumor regression, attenuates desmoplasia, and augments T cell infiltration in pancreatic ductal adenocarcinoma", "abstract_text": "Background: Pancreatic ductal adenocarcinoma (PDAC) is driven predominantly by oncogenic KRAS signaling and characterized by an immunosuppressive, fibrotic tumor microenvironment that limits therapeutic responses. RMC-6236, a pan-KRAS inhibitor, and ONIOYID, an investigational anti-tumor agent, each demonstrate partial activity in KRAS-mutant cancers. However, their combined therapeutic potential in PDAC remains unexplored. Here, we evaluated the anti-tumor efficacy, survival benefit, and immunomodulatory effects of RMC-6236, ONIOYID and irinotecan alone and dual combinations multiple in vitro and in vivo PDAC models.\nMethods: In vitro cytotoxicity assays were performed using KPC, PANC-1, AsPC-1, and PANC-02 cell lines. In vivo therapeutic studies were conducted in orthotopic KPC and PANC-1 tumor models. RMC-6236 was administered orally at 10 mg/kg; ONIOYID and irinotecan was administered intravenously at 5 mg/kg. Tumor growth inhibition, survival, collagen deposition, and immune cell infiltration were analyzed. Tumor microenvironment remodeling was quantified via immunohistochemistry for CD8, CD4, collagen I, and fibronectin.\nResults: The combination of RMC-6236 and ONIOYID elicited potent anti-tumor effects across all evaluated PDAC cell lines, achieving greater than 90% growth inhibition in vitro. In vivo, co-treatment resulted in more than 90% tumor regression in both KPC and PANC-1 xenograft models, markedly surpassing the efficacy of individual monotherapies and other dual-agent controls. Combination therapy significantly extended overall survival and produced sustained suppression of tumor progression. Mechanistic analyses revealed a substantial reduction in collagen and fibronectin deposition within the tumor microenvironment, consistent with attenuation of desmoplasia. Immune profiling demonstrated a robust enhancement of intratumoral CD8⁺ and CD4⁺ T-cell infiltration, along with a pronounced decrease in survivin expression. Importantly, no observable systemic toxicity was detected in treated animals.\nConclusions: RMC-6236 combined with ONIOYID yields synergistic anti-tumor effects, remodels the fibrotic PDAC microenvironment, enhances T-cell infiltration, and significantly improves survival in aggressive pancreatic tumor models. These findings provide strong rationale for clinical evaluation of RMC-6236-based combination therapies for KRAS driven PDAC.", "source_company": "Mayo Clinic", "source_org_type": "医院", "row_number": 467, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "B32B3", "company": "Huazhong University of Science and Technology Tongji Hospital", "org_type": "医院", "target": "DCAF1", "modality": "inhibitor", "importance_level": "中", "total_score": 55.5, "institution_score": 35, "track_score": 75, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "B32B3为DCAF1抑制剂，通过阻断DAPK3-DCAF1轴稳定ZBP1，促进PANoptosis和抗肿瘤免疫，在卵巢癌PDX模型中显示抑瘤效果。机构为医院非头部药企得分较低，但靶点机制新颖且涉及免疫-肿瘤热门通路，preclinical数据较扎实故综合为中重要性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10802", "id": "N1XM_5wBX1NQZOEH-LK6", "source_drug_name": "B32B3", "title": "DAPK3-DCAF1 pathway regulates ZBP1 protein stability to orchestrate innate immune responses and PANoptosis", "abstract_text": "Background: Z-DNA binding protein 1 (ZBP1) is an interferons (IFN)-stimulated cytosolic sensor of Z-nucleic acids (Z-NA) that regulates PANoptosis (pyroptosis, apoptosis, and/or necroptosis) and thereby drives potent anti-tumor immune responses. However, the mechanisms controlling ZBP1 protein stability in tumors—and whether they can be therapeutically manipulated to induce ICD—remain unclear. We sought to define regulatory pathways that govern ZBP1 abundance in ovarian cancer and to test strategies that exploit ZBP1 activation for antitumor therapy.\nMethods & Results: Here we demonstrate that the reduced ZBP1 expression in ovarian cancer and correlated with poorer survival. Type I IFN (IFN-β) rapidly increased ZBP1 levels by inhibiting its proteasome-dependent ubiquitination. Proximity labeling and biochemical assays identified DCAF1 as a key interactor that mediates ZBP1 ubiquitination and degradation. Furthermore, IP-MS and LC-MS/MS identified DAPK3 as an IFN-induced DCAF1 kinase, which phosphorylates DCAF1-pS1328 to promote its turnover, thereby stabilizing ZBP1. Genetic ablation of DCAF1 impaired tumor cell proliferation in vitro, reduced tumor burden and promoted anti-tumor immunity in vivo. Pharmacological targeting of this pathway using the DCAF1 inhibitor B32B3 and—when combined with the Z-NA activator CBL0137—effectively reactivated ZBP1 signaling, promoted PANoptosis, and enhanced antitumor immunity, thereby suppressing tumor growth in two chemotherapy-resistant ovarian cancer patient-derived xenograft (PDX) models and providing a promising therapeutic strategy for refractory malignancies.\nConclusion: Overall, this study delineates a novel DAPK3-DCAF1 signaling axis that governs ZBP1 stability, unveiling an integrated regulatory framework that connects interferon signaling, post-translational modification, and immunogenic cell death. Combining DCAF1 blockade with Z-NA activation elicits ZBP1-mediated PANoptosis and augments anti-tumor immunity, representing a promising therapeutic approach for refractory ovarian cancer.", "source_company": "Huazhong University of Science and Technology Tongji Hospital", "source_org_type": "医院", "row_number": 519, "target_meta": "DCAF1", "MOA_meta": "抑制剂"}, {"drug_name": "DIRAS3 mimetic peptide", "company": "The University of Texas MD Anderson Cancer Center", "org_type": "医院", "target": "KRAS", "modality": "other", "importance_level": "中", "total_score": 55.5, "institution_score": 35, "track_score": 85, "milestone_score": 45, "field_heat_score": 80, "bonus_score": 6, "brief_reason": "DIRAS3 mimetic peptide通过干扰KRAS nanoclustering实现对G12X和Q61X等多种KRAS突变体的MAPK和PI3K双通路抑制，对Q61X显示优于现有三复合物抑制剂的广谱潜力。机构为顶级肿瘤医院但非商业公司、仍处早期功能验证阶段导致总分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4353", "id": "QFXM_5wBX1NQZOEH-LK6", "source_drug_name": "DIRAS3 mimetic peptide", "title": "DIRAS3 mimetic peptide achieves dual MAPK and PI3K pathway suppression across KRAS hotspot mutations", "abstract_text": "Activating mutations in RAS occur in approximately 30% of human cancers, with hotspot alterations at codons G12, G13, and Q61 driving persistent downstream signaling through the MAPK and PI3K pathways. Although recent tricomplex RAS inhibitors have shown promise, their efficacy varies among different RAS mutants. Accumulating evidence indicates that the biochemical and signaling properties of G12X and Q61X mutants differ substantially, influencing their response to upstream and downstream modulation. G12X mutants depend on receptor tyrosine kinase activity for both MAPK and PI3K pathway activation, whereas Q61X mutants can independently activate MAPK signaling and maintain PI3K output even when RAS is inhibited. Consequently, Q61X tumors display intrinsic resistance to current RAS-targeted therapies, underscoring the need for agents capable of simultaneously suppressing both effector arms. DIRAS3 has emerged as a unique endogenous RAS inhibitor that disrupts RAS nanoclustering and effector engagement, while also modulating the PI3K/AKT axis in ovarian and pancreatic cancers, suggesting broader regulatory potential. To systematically define DIRAS3’s inhibitory spectrum, we utilized RASless mouse embryonic fibroblasts (MEFs) reconstituted with individual KRAS hotspot alleles. DIRAS3 expression markedly reduced RAS-dependent clonogenic growth, inhibited MAPK and PI3K/AKT signaling in cells expressing oncogenic KRAS variants, with minimal effect on wild-type KRAS unless stimulated with EGF. Functional analysis demonstrated that both N- and C-terminal domains of DIRAS3 are essential for membrane localization and full inhibitory activity. Importantly, DIRAS3 disrupted KRAS nanoclustering in both G12X and Q61X mutant backgrounds, supporting its capacity to interfere directly with the KRAS-KRAS interface. To recapitulate DIRAS3's inhibitory effects, we designed a conformationally constrained cyclic DIRAS3 mimetic peptide based on the sequence spanning parts of α5 and the hypervariable regions critical for DIRAS3-KRAS binding. For translational comparison, we evaluated the tricomplex RAS inhibitor RMC-7977 alongside this DIRAS3-derived peptide. In G12X cells, both agents suppressed MAPK and PI3K outputs. However, in Q61X cells, RMC-7977 inhibited MAPK signaling but failed to suppress PI3K/AKT activity, whereas the DIRAS3 peptide effectively suppressed both pathways. Reduced PI3K activity correlated with enhanced sensitivity to the DIRAS3 peptide, and cells harboring Q61X mutations, which are less responsive to RMC-7977, remained equally responsive to the DIRAS3 peptide. Collectively, these results indicate that DIRAS3 provides a dual-pathway blockade of MAPK and PI3K signaling across diverse KRAS mutations, including Q61X variants that are refractory to existing agents, supporting its development as a broad-spectrum therapeutic for RAS-driven cancers.", "source_company": "The University of Texas MD Anderson Cancer Center", "source_org_type": "医院", "row_number": 526, "target_meta": "KRAS", "MOA_meta": "其他"}, {"drug_name": "CHK1 inhibitor ADC", "company": "University of Bern", "org_type": "大学", "target": "HER2", "modality": "ADC", "importance_level": "中", "total_score": 55.5, "institution_score": 30, "track_score": 85, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 5, "brief_reason": "该ADC以CHK1抑制剂作为新型payload，靶向HER2，旨在解决现有ADC耐药和毒性问题，机制创新且属于热门ADC赛道。机构为大学非商业化早期研究，preclinical阶段显示体内外活性及安全性，但缺乏临床进展。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5384", "id": "blXM_5wBX1NQZOEH-LK6", "source_drug_name": "CHK1 inhibitor ADC", "title": "First-in-class CHK1 inhibitor antibody-drug conjugate overcomes limitations of current ADC payloads and provides a new option for HER2-positive and TOP1 inhibitor-resistant tumors", "abstract_text": "Background:\nCurrent ADCs rely almost exclusively on two payload classes -TOP1 poisons and microtubule inhibitors- leading to significant toxicity, frequent dose interruptions and reductions, and limited options once resistance develops. To address these limitations, we developed a first-in-class ADC incorporating a novel payload class: a CHK1 inhibitor (CHK1i). The novel payload exploits the presence of DNA replication stress in cancer, leading to greater selectivity.\nMethods:\nTrastuzumab variants containing engineered cysteines were generated to enable site-specific conjugation. A proprietary cleavable linker was synthesized and conjugated to the CHK1i payload. The resulting ADC was evaluated for HER2-dependent activity in vitro and tested in vivo in a HER2-positive breast cancer xenograft model (HCC1569).\nResults:\nAs a small molecule, the CHK1i was about 50-fold less toxic to normal cells than a TOP1 poison (deruxtecan) while maintaining comparable potency in cancer cell lines. When bound to the ADC linker, the CHK1i was not toxic to cells, in contrast to the deruxtecan-linker, which retains toxicity.\nTrastuzumab with five engineered cysteines, combined with a novel cleavable linker and a CHK1i as payload, enabled enhanced ADC potency and selective killing of HER2-positive cancer cells. In vivo testing of the ADC, administered intravenously once per week for five consecutive weeks, demonstrated antitumor efficacy at 10 mg/kg in the HCC1569 xenograft model. Mice were monitored for three weeks after treatment completion, and tumor growth inhibition was still observed. No body weight loss or obvious signs of toxicity were detected.\nConclusions:\nThis first-in-class CHK1i ADC expands payload diversity, aims to address resistance to existing ADCs and reduce nonspecific toxicity, offering the potential for a wider therapeutic window.", "source_company": "University of Bern", "source_org_type": "大学", "row_number": 557, "target_meta": "HER2", "MOA_meta": "抗体偶联药物"}, {"drug_name": "UMB-J17", "company": "Brigham and Women’s Hospital, Harvard Medical School", "org_type": "医院", "target": "PARP2-FOXA1 interaction", "modality": "inhibitor", "importance_level": "中", "total_score": 55.5, "institution_score": 35, "track_score": 75, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 4, "brief_reason": "UMB-J17为选择性小分子抑制剂，通过破坏PARP2-FOXA1相互作用抑制AR信号通路，在CRPC模型中显示良好体外/体内抗肿瘤活性及与AR抑制剂协同作用。机构为学术医院导致机构分较低，但新机制+前列腺癌耐药未满足需求使赛道和领域热度较高，整体处于中等重要性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8876", "id": "i1XM_5wBX1NQZOEH-LK6", "source_drug_name": "UMB-J17", "title": "Selective PARP2 inhibitor disrupting PARP2-FOXA1 interaction to inhibit androgen receptor signaling in prostate cancer", "abstract_text": "Currently targeting androgen receptor (AR) pathways is the primary treatments for advanced prostate cancer (PCa). However, resistance to AR pathway inhibitors and emergence of castration-resistant prostate cancer (CRPC) remain a significant clinical challenge. We previously found that PARP2 interacts with FOXA1 to facilitate the recruitment of AR to genome-wide prostate-specific enhancer regions. Selective disruption of the PARP2-FOXA1 interaction inhibited AR signaling and PCa growth. However, lack of selectivity and potency of existing PARP2/FOXA1-targeting agents and uncertainty of the functional importance of PARP2-FOXA1 binding have limited our study. To address these gaps, we developed a potent small molecule inhibitor UMB-J17 that disrupts PARP2-FOXA1 interaction. In this study, we demonstrated that UMB-J17 competes with FOXA1 for the same PARP2 binding sites, and significantly suppresses AR signaling and PCa cell growth without involving AR-ligand binding. Preclinical studies demonstrated that UMB-J17 exerts potent anti-tumor effects in both in vitro and in vivo CRPC models. UMB-17 also exhibits potent synthetic effect with AR pathway inhibitors in enzalutamide-resistant CRPC models. Furthermore, UMB-J17 enhanced the synthetic lethality of PARP inhibition through AR signaling suppression in PCa. These findings identify UMB-J17 as a promising therapeutic agent that targets PARP2/FOXA1/AR axis for AR signaling inhibition, which is urgently needed to improve CRPC patient outcomes.", "source_company": "Brigham and Women’s Hospital, Harvard Medical School", "source_org_type": "医院", "row_number": 575, "target_meta": "PARP2,FOXA1", "MOA_meta": "抑制剂"}, {"drug_name": "a clinically relevant ADC", "company": "Aliri", "org_type": "CRO", "target": "未披露", "modality": "ADC", "importance_level": "中", "total_score": 55.5, "institution_score": 45, "track_score": 85, "milestone_score": 40, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "该ADC靶点和具体机制未披露，仅为临床相关ADC的空間PK/PD研究框架展示；Aliri作为专注生物分析和空间组学的CRO而非药企，机构分较低，但ADC赛道热度高，研究具方法学创新价值。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4418", "id": "t1XM_5wBX1NQZOEH-LK6", "source_drug_name": "a clinically relevant ADC", "title": "A spatial PK/PD framework predicts ADC response in solid tumors by integrating drug delivery, target engagement, and microenvironmental readiness", "abstract_text": "Background: Antibody-drug conjugates achieve their effect only when payload delivery, target accessibility, and microenvironmental readiness align within the tumor. Conventional biomarkers capture fragments of this biology, but not the spatial interplay that ultimately determines response. To address this gap, we conducted a translational spatial PK/PD study to determine whether high-resolution tissue mapping could predict early ADC activity in solid tumors.\nMethods: Tumor biopsies from patients and PDX models treated with a clinically relevant ADC were analyzed using an integrated spatial PK/PD workflow. Quantitative payload imaging by mass spectrometry imaging was combined with spatial proteomics and transcriptomics to map antigen distribution, stromal architecture, vascular organization, immune niches, and early pharmacodynamic activation. All data modalities were spatially registered and modeled using AI-based neighborhood analysis to generate a continuous delivery-engagement score for each tumor region. Importantly, pharmacodynamic readouts such as cleaved caspase-3 and γH2AX were evaluated in a blinded manner.\nResults: Across fourteen matched tumor samples, the analysis revealed a consistent pattern linking spatial drug behavior with early biological response. Regions showing strong spatial convergence between payload localization and antigen-rich tumor pockets exhibited significantly higher apoptotic signaling. Tumors displaying coherent payload influx along perfused vascular corridors were more likely to show downstream pharmacodynamic activation, regardless of their bulk target expression. In addition, microenvironments enriched for dendritic cells, CD8⁺ T cells, and interferon-responsive stromal states demonstrated enhanced sensitivity to the ADC even before radiographic change. When integrated into a unified spatial competency score, these features correctly classified early responses in eleven of fourteen samples.\nConclusion: This study shows that a spatial PK/PD framework can predict ADC response by capturing the coordinated alignment of delivery, target engagement, and microenvironmental readiness within tissue. These findings provide a mechanistically grounded, clinically relevant approach for improving patient selection and advancing predictive biomarker strategies for next-generation ADCs.", "source_company": "Aliri", "source_org_type": "公司\n未知", "row_number": 606, "target_meta": "not available", "MOA_meta": "抗体偶联药物"}, {"drug_name": "Bria-ABC", "company": "BriaCell Therapeutics Corporation", "org_type": "医院", "target": "未披露", "modality": "other", "importance_level": "中", "total_score": 55.5, "institution_score": 30, "track_score": 70, "milestone_score": 85, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "Bria-ABC为晚期转移性乳腺癌的III期试验，涉及Bria-IMT（SV-BR-1-GM细胞免疫疗法）联合检查点抑制剂，靶点未在摘要中明确披露。机构为Mayo Clinic（医院类型）得分较低，但III期注册性试验里程碑价值高，细胞免疫疗法在乳腺癌领域有一定热度。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/12137", "id": "wlXM_5wBX1NQZOEH-LK6", "source_drug_name": "Bria-ABC", "title": "QOL outcomes in Bria-ABC late stage metastatic phase 3 trial", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Mayo Clinic", "source_org_type": "医院", "row_number": 610, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "MTX-5-FU-Gem-miR-15a", "company": "Stony Brook University", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "中", "total_score": 55.5, "institution_score": 25, "track_score": 75, "milestone_score": 75, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "该药物为多模式miR-15a模拟物复合物（含MTX、5-FU、Gem），旨在通过恢复miR-15a水平靶向DNA修复和存活通路克服卵巢癌PARPi耐药。大学机构基础分较低，但preclinical体内外数据强劲（显著抑瘤、协同、生存改善），miRNA+化疗+靶向递送赛道有一定创新性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/2310", "id": "6FXM_5wBX1NQZOEH-LK6", "source_drug_name": "MTX-5-FU-Gem-miR-15a", "title": "Developing MTX-5-FU-Gem-miR-15a as a multimodal therapeutic strategy to overcome olaparib resistance in epithelial ovarian cancer", "abstract_text": "Epithelial ovarian cancer (EOC) is the deadliest gynecological cancer, mainly because of late diagnosis, high relapse (~70%), and drug resistance, including resistance to PARP inhibitors (PARPi). Olaparib, a common PARP inhibitor, is most effective in homologous recombination-deficient (HRD) tumors. However, resistance often develops by activating other DNA repair pathways, such as the ATR/CHK1/WEE1 axis. Several studies show that blocking this pathway can restore olaparib sensitivity in resistant EOC models. miR-15a is often decreased in EOC and targets important regulators of DNA repair, cell-cycle progression, and survival, like WEE1, CHK1, BCL2, and YAP1, indicating that restoring miR-15a could help re-sensitize resistant tumors to PARPi. To enhance therapeutic efficacy, stability and tumor cell specificity, we engineered a multimodal MTX-5-FU-Gem-miR-15a combining the therapeutic power of tumor suppressor miR-15a with methotrexate (MTX), 5-fluorouracil (5-FU), and gemcitabine (Gem). MTX improves tumor specificity by targeting overexpressed folate receptor in EOC cells. Furthermore, the incorporation of 5-FU and Gem allows the construct to both disrupt DNA repair pathways and increase DNA damage burden. Hence, we hypothesized that miR-15a mimic treatment could suppress these pathways and re-sensitize resistant EOC to PARPi.MTX-5-FU-Gem-miR-15a robustly inhibited viability of olaparib-resistant EOC cells (IC50: 5–15 nM) without a delivery vehicle, induced S-phase arrest, and markedly increased apoptosis. The therapeutic efficacy of MTX-5-FU-Gem-miR-15a was improved by over 1000-fold compared to that of Olaparib. Combining MTX-5-FU-Gem-miR-15a with olaparib was significantly more effective than either agent alone. (BLISS Synergy score: 13.2). Transcriptomic profiling revealed downregulation of pathways linked to PARPi resistance, and suppression of pro-survival signaling including PI3K–AKT, mTOR, WNT pathways, consistent with broad disruption of resistance-associated networks. The mimic also retained potency in cancer stem–like (CSCs) spheroids (IC50: ~3 nM) without any delivery vehicle. To evaluate therapeutic efficacy in vivo, a metastatic olaparib-resistant EOC model was established by tail-vein injection of olaparib resistant EOC cells into NOD/SCID mice. MTX-5-FU-Gem-miR-15a treatment (3.75 mg/kg) reduced tumor burden by >5.5-fold (~80%) and significantly improved survival without observable toxicity or weight loss. Statistical significance was determined using Student’s t-test or two-way ANOVA (p < 0.05). Overall, these findings demonstrate that MTX-5FU-Gem-miR-15a is a powerful multimodal miRNA-based therapeutic as it has the potential to exert strong antitumor effects in EOC and overcome drug resistance, supporting its potential as a next-generation strategy to improve patient outcomes.", "source_company": "Stony Brook University", "source_org_type": "大学", "row_number": 637, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "MUC4-directed CAR-T cells", "company": "Medical University of South Carolina", "org_type": "大学", "target": "MUC4", "modality": "CAR", "importance_level": "中", "total_score": 55.5, "institution_score": 35, "track_score": 75, "milestone_score": 70, "field_heat_score": 65, "bonus_score": 3, "brief_reason": "靶向MUC4的CAR-T细胞在化疗耐药结直肠癌模型中显示显著体内疗效，机制涉及IFN-γ介导的凋亡增强。机构为大学学术机构得分较低，但CAR-T在实体瘤的探索及化疗耐药突破带来较高赛道与里程碑价值。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5216", "id": "7lXM_5wBX1NQZOEH-LK6", "source_drug_name": "MUC4-directed CAR-T cells", "title": "Development of MUC4-directed CAR-T cells against chemoresistant colorectal carcinoma", "abstract_text": "Colorectal adenocarcinoma remains a leading cause of cancer mortality, with chemoresistance and metastatic progression severely limiting treatment options. MUC4, a membrane-bound mucin normally confined to the apical epithelial surface, becomes aberrantly overexpressed across the tumor cell membrane in colorectal and other epithelial cancers. This dysregulated expression promotes immune evasion, cancer survival and metastasis. Therefore, MUC4 serves as a promising candidate for the development of targeted CAR-T therapies. We engineered MUC4-specific CAR-T cells and evaluated their activity against human colorectal cancer cell lines representing distinct clinical features: HT29 (parental), HT29-MTX (methotrexate-resistant), and T84 (metastatic). MUC4 expression was quantified by flow cytometry. Tumor cell responsiveness to IFN-γ and CAR-T-mediated cytotoxicity were assessed in vitro. For in vivo studies, HT29-MTX cells were injected intraperitoneally into NSG mice, creating a highly aggressive and lethal tumor model in which tumor-bearing mice succumb within 30-35 days, to determine the therapeutic impact of MUC4 CAR-T cells. All lines expressed high MUC4 levels. Interestingly, MUC4 CAR-T cells efficiently eliminated HT29-MTX and T84 cells but not HT29 cells. IFN-γ treatment upregulated MHC-I and PD-L1 expression across all lines. However, only HT29-MTX and T84 cells underwent robust IFN-γ-induced apoptosis, paralleling CAR-T cell killing, suggesting that IFN-γ secreted by MUC4 CAR-T cells might contribute to tumor clearance. Strikingly, in an intraperitoneal HT29-MTX tumor growth model, MUC4 CAR-T treatment significantly reduced tumor burden, demonstrating therapeutic efficacy in a setting where chemotherapy typically fails. Mouse necropsy analysis revealed no off-target in vivo toxicities associated with MUC4 CAR-T cell therapy. Our findings establish MUC4 as a potent and clinically relevant CAR-T cell target and demonstrate that MUC4 CAR-T cells control tumor progression in an aggressive human colorectal cancer in vivo model. These results highlight the potential of MUC4-targeted CAR-T cell therapy to fill a critical treatment gap for patients with chemoresistant colorectal cancer and may extend to other MUC4-expressing solid tumors.\nFunding: This work was supported by Swim Across America Grant 23-1579 to LMRF and an MUSC Specialized Center of Research Excellence (SCORE) 5U54DA016511-18 Pilot Project Award to AC. This study was supported in part by the Flow Cytometry and Cell Sorting Shared Resource, Hollings Cancer Center, Medical University of South Carolina (P30 CA138313).", "source_company": "Medical University of South Carolina", "source_org_type": "大学", "row_number": 642, "target_meta": "MUC4", "MOA_meta": "其他"}, {"drug_name": "22C12", "company": "Albert Einstein College of Medicine", "org_type": "大学", "target": "ART1", "modality": "monoclonal antibody", "importance_level": "中", "total_score": 55.5, "institution_score": 35, "track_score": 75, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "22C12为全人源化抗ART1单抗，靶向ART1阻断其单ADP-核糖化修饰EGFR信号并调控免疫抑制，在EGFR突变NSCLC模型中与osimertinib协同实现肿瘤清除并进入I期临床前准备。机构为大学学术型，得分偏低，但新型免疫检查点+双重肿瘤内在与免疫调控机制+热门肺癌适应症赛道具较高热度与潜力。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5688", "id": "-VXM_5wBX1NQZOEH-LK6", "source_drug_name": "22C12", "title": "ART1 as an immune modulating therapeutic target in EGFR-mutated lung cancer", "abstract_text": "Purpose: Epidermal growth factor receptor (EGFR) mutations drive non-small cell lung cancer (NSCLC). Tyrosine kinase inhibitors (TKIs) provide clinical benefit but are limited by resistance. We investigated the role of mono-ADP-ribosyltransferase-1 (ART1) in mediating EGFR signaling, immune suppression, and therapeutic resistance.\nMethods: ART1 expression was assessed in a human tissue microarray. ART1 function was assessed in vitro in HCC827 and other EGFRmu lines using immunoprecipitation, immunofluorescence, and RNA-seq to define MARylation events and transcriptional changes. In vivo studies tested ART1 blockade with the fully humanized anti-ART1 monoclonal antibody, 22C12, alone or in combination with osimertinib in EGFR-mutant NSCLC GEMMs. These approaches enabled integrated assessment of ART1’s biochemical, transcriptional, and immunologic functions.\nResults: ART1 protein expression was higher in EGFRmu than EGFRwt human tumors. In vitro, ART1 was increased by osimertinib treatment. ART1 enhanced EGFR signaling through NAD⁺-dependent mono-ADP-ribosylation (MARylation). ART1 blockade with 22C12 abrogated EGFR MARylation and reduced downstream oncogenic signaling. RNA-seq revealed ART1-dependent regulation of EGFR-related transcriptional programs. In vivo, 22C12 osimertinib and 22C12 each demonstrated single agent efficacy, however small tumors persisted in GEMM models. However, combination therapy with Osimertinib and 22C12 reduced macrophage infiltration, increased tumor-infiltrating CD8⁺ tissue-resident memory (TRM) T cells, and rendered treated mice tumor-free. This synergy highlighted complementary tumor-intrinsic and immune-modulatory roles of ART1. These dual tumor-intrinsic and immune-modulatory effects identify ART1 as a driver of therapeutic resistance and potential therapeutic target.\nConclusions: ART1 promotes EGFR pathway activation and suppresses antitumor immunity in EGFR-mutant NSCLC. Targeting ART1 enhances efficacy of TKIs while decreasing macrophage infiltration and reinvigorating CD8⁺ T-cell responses. ART1 inhibition represents a promising therapeutic strategy for overcoming resistance, warranting further investigation including ADP-ribosylome mapping and studies on ART1 blockade in modulating receptor signaling and bispecific antibody or antibody-drug conjugate interactions. Overall, these results support ART1 as a targetable mediator of EGFR-driven tumor progression and immune dysfunction in EGFR-mutant lung cancer. 22C12 is being developed to enter phase 1 clinical trials across multiple tumor types.", "source_company": "Albert Einstein College of Medicine", "source_org_type": "大学", "row_number": 649, "target_meta": "ART1", "MOA_meta": "单抗"}, {"drug_name": "IP-DNQ", "company": "Indiana University School of Medicine", "org_type": "大学", "target": "NQO1", "modality": "other", "importance_level": "中", "total_score": 55.5, "institution_score": 35, "track_score": 75, "milestone_score": 70, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "IP-DNQ为NQO1生物激活的醌类化合物，通过产生ROS诱导氧化DNA损伤，与PARP抑制剂协同触发焦亡。大学机构背景限制分数，但NQO1靶向+新型氧化应激机制+动物模型有效性使其在preclinical阶段具一定潜力。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5653", "id": "FlXM_5wBX1NQZOEH-LO6", "source_drug_name": "IP-DNQ", "title": "Redox-DNA repair co-targeting with IP-DNQ and rucaparib induces oxidative DNA damage and GSDME-mediated pyroptosis in NQO1-positive tumors", "abstract_text": "Cancer remains a leading cause of mortality worldwide, with current therapies often failing to eradicate resistant tumor populations. This highlights the need for strategies that exploit tumor-specific metabolic and DNA repair vulnerabilities. NAD(P)H:quinone oxidoreductase 1 (NQO1), commonly overexpressed in solid tumors, enzymatically activates redox-cycling prodrugs, offering a selective tumor targeting strategy. Isopentyl-deoxynyboquinone (IP-DNQ), a potent NQO1-bioactivatable quinone, undergoes futile redox cycling to generate reactive oxygen species (ROS), induce oxidative DNA damage, and deplete NAD⁺/ATP. Given that PARP activation is an early response to DNA damage, we investigated the mechanistic synergy between NQO1-dependent redox cycling and PARP inhibition using IP-DNQ combined with rucaparib, an FDA-approved PARP inhibitor. Rucaparib significantly enhanced IP-DNQ-induced ROS accumulation, DNA strand breaks, and metabolic collapse in an NQO1-dependent manner. This combination triggered caspase-3 activation and gasdermin E (GSDME) cleavage, leading to pyroptotic cell death characterized by LDH release and IL-1β secretion. Both pharmacologic inhibition and genetic knockout of NQO1 abolished these effects, confirming the essential role of IP-DNQ bioactivation. Importantly, the IP-DNQ/rucaparib combination suppressed tumor growth and prolonged survival in orthotopic pancreatic and lung cancer models without causing systemic toxicity. These findings uncover a novel redox-DNA repair co-targeting strategy that amplifies oxidative DNA damage and redirects apoptosis toward immunogenic GSDME-mediated pyroptosis. This approach broadens the therapeutic scope of PARP inhibitors and offers a promising platform for treating NQO1-overexpressing cancers.", "source_company": "Indiana University School of Medicine", "source_org_type": "大学", "row_number": 664, "target_meta": "NQO1", "MOA_meta": "其他"}, {"drug_name": "anti-CTLA-4", "company": "Rice University", "org_type": "大学", "target": "CTLA-4", "modality": "inhibitor", "importance_level": "中", "total_score": 55.5, "institution_score": 35, "track_score": 75, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "药物为anti-CTLA-4抑制剂，靶向CTLA-4免疫检查点，与Alpha DaRT放射疗法联合在mtKRAS PDAC模型中显示协同效应及局部/系统性抗肿瘤免疫。大学机构得分较低，但免疫+放射组合在免疫冷肿瘤领域有一定机制创新和preclinical潜力。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3955", "id": "GlXM_5wBX1NQZOEH-LO6", "source_drug_name": "anti-CTLA-4", "title": "Alpha-particle radiotherapy combined with anti-CTLA-4 synergistically overcomes radioresistance and induces local and systemic antitumor immunity in PDAC", "abstract_text": "Pancreatic ductal adenocarcinoma (PDAC) is the third leading cause of cancer death in the U.S., with over 90% of patients presenting mutant KRAS (mtKRAS). Increased radioresistance and elevated CTLA-4 expression are hallmarks driven by mtKRAS. Radiation has only shown meaningful efficacy in PDAC at very high doses that are not achievable with conventional radiotherapy due to toxicity to adjacent organs. Additionally, although CTLA-4 upregulation suggests a therapeutic target, PDAC shows limited response to immune checkpoint blockade because of its highly immunosuppressive tumor microenvironment. We propose to sensitize a cold mtKRAS murine PDAC model (KPC) to anti-CTLA-4 (aCTLA-4) by overcoming radioresistance using Diffusing Alpha-emitters Radiation Therapy (Alpha DaRT), an intratumoral source of alpha particles with >1,000-fold greater ionization density than photons. This enables delivery of very high doses directly to the tumor while sparing healthy tissue. To further enhance this effect, an ATR inhibitor will impair DNA repair, increasing susceptibility to treatment. To assess local tumor response, mice received 5×10⁵ cells in the left leg, and after 7 days (day 0) one DaRT source (inert or active) was implanted. ATRi (75 mg/kg) or DMSO was administered orally on days 0, 1, 2, 7, 8, and 9, and aCTLA-4 or IgG was injected intraperitoneally every 3 days starting on day 3 (4 doses). Animals with complete regression (>100 days tumor-free) were rechallenged on day 130. To assess systemic immunity, mice received 5×10⁵ KPC cells in the left leg and 1×10⁵ in the right leg, and after 10 days (day 0) one DaRT source was implanted in the left leg. The drug schedule was identical, except mice received six doses of aCTLA-4. The triple therapy (Alpha DaRT + ATRi + aCTLA-4) induced significantly (p<0.05) greater tumor growth delay compared to control, monotherapies, and duotherapies, excluding Alpha DaRT + aCTLA-4, from day 25 onward. By day 41, all control and monotherapy mice reached euthanasia criteria, whereas 60% and 70% of the Alpha DaRT + aCTLA-4 and triple therapy groups remained alive. Complete tumor regression >100 days was sustained in 40% and 50% of mice, respectively. Upon rechallenge, no tumors regrew in the Alpha DaRT + aCTLA-4 group, and only 1 of 5 in the triple therapy group showed regrowth. A significant (p<0.0001) synergistic effect was observed between Alpha DaRT and aCTLA-4. For systemic immunity, Alpha DaRT + aCTLA-4 and the triple therapy induced greater tumor growth delay in both the irradiated and unirradiated tumors compared to all other treatments. In conclusion, Alpha DaRT combined with aCTLA-4 generates durable local and systemic antitumor responses in mtKRAS PDAC, offering a strategy to overcome KRAS-mediated radioresistance and immune evasion.", "source_company": "Rice University", "source_org_type": "大学", "row_number": 667, "target_meta": "CTLA4", "MOA_meta": "抑制剂"}, {"drug_name": "Antibody-drug conjugates", "company": "Reaction Biology Europe GmbH", "org_type": "CRO", "target": "未披露", "modality": "ADC", "importance_level": "中", "total_score": 55.5, "institution_score": 45, "track_score": 85, "milestone_score": 40, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "该摘要为CRO公司Reaction Biology Europe GmbH开发的ADC体外/体内PK分析平台方法研究，未披露具体药物靶点或候选药物，仅为技术平台展示。ADC赛道热度高，但作为服务型CRO非药企本体研发、仅preclinical方法学、无明确里程碑价值，得分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4582", "id": "XZ7ECZ0BZznHJdntvNYd", "source_drug_name": "Antibody-drug conjugates", "title": "A sensitive MSD-ECL platform for in vivo pharmacokinetic profiling of ADCs", "abstract_text": "Antibody-drug conjugates (ADCs) are a rapidly evolving class of targeted cancer therapeutics that combine the specificity of monoclonal antibodies with the potency of small-molecule cytotoxic drugs. It is critical for ADCs to be stable in the systemic circulation in order to prevent premature release of the payload, which can lead to off-target toxicity and reduced therapeutic efficacy. The pharmacokinetic (PK) behavior of ADCs is influenced by several factors, such as antibody structural heterogeneity, linker type, and payload physicochemical properties. Stability is a key quality attribute that directly affects dosing strategies, the therapeutic window, and clinical outcomes. Therefore, robust and sensitive analytical platforms are essential for monitoring ADC integrity and payload release over time. While traditional ELISA-based methods are widely used, they often lack the sensitivity and dynamic range required to detect subtle changes in ADC composition during circulation. In this study, we use the Meso Scale Discovery® (MSD) platform, which uses plate-based electrochemiluminescence (ECL) technology, to evaluate the in vivo PK and stability of ADCs. By applying this technology to preclinical in vivo models, we aim to generate high-resolution PK profiles and stability data that support the rational design and optimization of ADCs for clinical development.\nStandard 1-Spot SECTOR plates were used to detect the antibody backbone by coating them with a specific capture antibody. Small Spot Streptavidin SECTOR plates were used to detect the intact ADC, capturing the molecule via anti-payload antibodies. In both assays, detection was performed using a sulfo-tagged anti-human IgG antibody. After optimizing the setup, it demonstrated a broad dynamic range of 4-5 orders of magnitude and a lower limit of detection of less than 100 pg/mL for both the antibody and the intact ADC. Subsequent in vivo PK studies involved administering ADCs via a single intravenous injection to SCID beige mice. Serum samples were diluted 1:1000 in PBS containing 1% BSA, and 25 µL per well was applied to the MSD plates. This high dilution factor permits minimal blood volume collection per time point, thereby reducing the number of animals required. The assay demonstrated excellent reproducibility with minimal variability between replicates. To further increase the relevance of the results, future studies may use mFcRn⁻/⁻ hFcRn transgenic mice or HSA/hFcRn/hFcγR triple transgenic models. These models more accurately reflect the serum half-life of human IgG and correlate well with data from cynomolgus monkeys and humans.\nIn summary, this MSD-based assay platform offers a highly sensitive and reproducible approach for in vivo PK analysis of ADCs that spares animals. There is potential to further refine this approach using humanized mouse models to improve clinical predictability.", "source_company": "Reaction Biology Europe GmbH", "source_org_type": "公司", "row_number": 693, "target_meta": "not available", "MOA_meta": "抗体偶联药物"}, {"drug_name": "SSR128129E", "company": "Weill Cornell Medicine", "org_type": "大学", "target": "FGFR1", "modality": "inhibitor", "importance_level": "中", "total_score": 55.5, "institution_score": 35, "track_score": 75, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 2, "brief_reason": "SSR128129E为FGFR1小分子抑制剂，可显著降低CAF中TGFβ分泌，逆转免疫抑制微环境并增强CD19及BAFFR CAR-T在B细胞淋巴瘤PDX模型中的抗肿瘤活性及生存获益。机构为大学得分较低，但FGFR1抑制在CAR-T联合赛道有较好preclinical强度及机制新颖性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10468", "id": "tVXM_5wBX1NQZOEH-LO6", "source_drug_name": "SSR128129E", "title": "FGFR1+ cancer-associated fibroblasts contribute to the failure of CAR-T cell therapy in B-cell lymphoma through the secretion of TGFβ", "abstract_text": "Despite significant advancements in chimeric antigen receptor (CAR) T-cell therapies targeting CD19 for relapsed B cell malignancies, over 50% of lymphoma patients do not achieve sustained remission. The roles of cancer-associated fibroblasts (CAF) in reprogramming lymphoma microenvironments and their relationship with CAR T-cell response are becoming increasingly evident. Evidence suggests that TGFβ-activated stromal gene signatures are enriched in immunosuppressive lymphoma microenvironments (LME) and in non-responder CAR T-cell patients (Cerchietti. Cancer Discovery 2021, Locke. Nature Medicine 2024). In previous studies using pre-clinical lymphoma models, we demonstrated that FGFR1 inhibition in CAFs can reverse extracellular matrix compositional changes and increase the secretion of several monocyte chemoattractant proteins, thereby promoting the infiltration of anti-lymphoma macrophages and inducing anti-tumor effect in FGFR1neg lymphoma cells (Di Siervi. Cancer Research 2024). We report now that FGFR1⁺ CAF are a consistent source of TGFβ. We discovered that TGFβ secretion in CAF is tightly regulated by FGFR1 activity. Genetic downregulation and pharmacological inhibition of FGFR1 (SSR128129E, FGFR1i) in three different activated fibroblast models led to a significant decrease in TGFβ transcription, expression, and secretion (p < 0.005). We developed a patient-derived xenograft (PDX) model from a B-cell lymphoma patient refractory to CD19 CAR T cell therapy, that we use to test the effect of pharmacological FGFR1 inhibition to the anti-tumor effect of human CD19-CAR T cells. Compared to vehicle, FGFR1i significantly reduced circulating tumor cells and increased circulating CAR T-cells (p < 0.005). These findings correlated with a reduced tumor burden and increased CAR T cell infiltration in the intrasplenic tumors.To further characterize CART-cell function, we analyzed exhaustion phenotype. We observed a significant reduction in exhausted CD4⁺ and CD8⁺ T-cell populations (PD1⁺ LAG3⁺) in the CART plus FGFR1i group (p< 0.05). Moreover, mice treated with the combination exhibited improved overall survival compared to those treated with CAR T cells alone (p< 0.05) or FGFR1i alone (p < 0.05). To test whether these results were specific for CD19-CAR T cells, we conducted similar experiments using BAFFR-CAR-T cells. Consistently, the combination of BAFFR-CAR T cells and FGFR1i increased CAR T cell expansion (p < 0.005), reduced T-cell exhaustion (p < 0.05), and improved overall survival compared to FGFR1i (p < 0.005) and CAR T cell therapy alone (p < 0.005). In conclusion, our findings suggest that the multifactorial changes induced by FGFR1i rewire the immunosuppressive LME, enhancing CAR T-cell infiltration, expansion, and antitumor activity.", "source_company": "Weill Cornell Medicine", "source_org_type": "大学", "row_number": 774, "target_meta": "FGFR1", "MOA_meta": "抑制剂"}, {"drug_name": "anti-HSPA5 ADC", "company": "University of Texas Health Science Center at Houston", "org_type": "大学", "target": "HSPA5", "modality": "ADC", "importance_level": "中", "total_score": 55.5, "institution_score": 35, "track_score": 75, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "靶点为HSPA5（GRP78），通过放疗诱导其癌细胞表面转位，实现anti-HSPA5 ADC的肿瘤特异性靶向；机构为大学，赛道ADC+辐射诱导靶点机制有一定新颖性，处于preclinical阶段显示体内外有效性和低毒性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9327", "id": "61XM_5wBX1NQZOEH-LO6", "source_drug_name": "anti-HSPA5 ADC", "title": "Exploiting radiation-induced tumor vulnerabilities via targeted antibody-drug conjugates", "abstract_text": "Background: Antibody-drug conjugates (ADCs) demonstrate potent anti-cancer activity but may cause on-target off-tumor toxicity in normal tissues if the target antigen is not strictly tumor-specific. To address this, we leverage on radiation therapy (RT), a main pillar in gastric (GC) and colorectal cancer (CRC) treatment, to kill cancer cells while simultaneously triggering a cancer-specific response that relocates Heat Shock Protein A5 (HSPA5). HSPA5 is intrinsically localized to the endoplasmic reticulum (ER). The ability of RT to promote HSPA5 translocation from ER to the cell surface (cs) opens an opportunity to target cancer cells with anti-HSPA5 ADC. We seek to understand RT-induced csHSPA5 biology and target it via ADC. \nMethods: We mined the TCGA data for HSPA5 expression in normal and GC or CRC tissues and for its correlation with patient prognosis. Irradiated human (AGS and MKN45) and murine (YTN16) GC, human (HCT116 and HT29) CRC cells were subjected to flow cytometry (FC) and immunofluorescence (IF) for csHSPA5 levels. csHSPA5+ cells’ tumorigenicity was examined by co-staining the cells with HSPA5 and Ki67 (proliferation), CD44 (stemness), N-cadherin (EMT) via FC. To examine the involvement of O-glycosylation in HSPA5 cell-surface presentation, we performed co-immunoprecipitation to detect potential O-glycosylation regulators and inhibited O-glycosylation in AGS (+/-RT). To assess HSPA5 antibody biodistribution, we injected GC/CRC nude mice with anti-HSPA5 antibody-Alexa Fluor 647 dye prior to imaging, with the tumors and organs harvested for FC and IF. Lastly, Annexin V/PI staining was performed with AGS and HUVEC cells treated with RT+anti-HSPA5 ADC.\nResults: Expression levels of HSPA5 are higher in GC and CRC against their normal counterparts and are correlated with worse patient prognosis. We detected RT-induced elevation of csHSPA5 in all GC/CRC cells, notably not in normal HUVEC or GES1. csHSPA5+ population is enriched for Ki67+, CD44+, and N-cadherin+ cells compared to csHSPA5- population, indicating the tumorigenic phenotypes of csHSPA5+ cells. Interestingly, our data revealed the cancer-specific csHSPA5 translocation mechanism, in which HSPA5 binds to N-acetylgalactosaminyltransferase 2 (GALNT2) and N-acetylgalactosamine (O-GalNAC) only in cancer cells but not normal cells. Inhibiting O-glycosylation blocks RT-induced HSPA5 cell-surface translocation. The in vivo models showed a significant accumulation of HSPA5 antibody in radiated tumors compared to non-irradiated tumors or healthy organs. Moreover, RT+ADC significantly decreased %live cells compared to RT or ADC alone. RT+ADC caused no decreased viability of the normal HUVEC cells, reflecting the low toxicity in healthy cells.\nConclusion: The overexpression of HSPA5 in cancer, coupled with radiation-induced cell-surface expression, renders it a promising ADC target for achieving high anti-tumor specificity.", "source_company": "University of Texas Health Science Center at Houston", "source_org_type": "大学", "row_number": 816, "target_meta": "BiP", "MOA_meta": "抗体偶联药物"}, {"drug_name": "VT00278", "company": "Coriell Institute for Medical Research", "org_type": "研究机构", "target": "YAP/TEAD", "modality": "inhibitor", "importance_level": "中", "total_score": 55.5, "institution_score": 30, "track_score": 85, "milestone_score": 60, "field_heat_score": 75, "bonus_score": 3, "brief_reason": "VT00278为新型YAP/TEAD抑制剂（CA3类似物），通过阻断YAP/TEAD转录活性并激活胞质DNA感知通路增强抗PD-1免疫治疗效果。机构为研究机构得分较低，但YAP/TEAD赛道在实体瘤尤其是GEAC领域热度高，前药理数据显示体内外强效及联合免疫清晰协同，综合潜力中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4049", "id": "AlXM_5wBX1NQZOEH-LS6", "source_drug_name": "anti-PD-1", "title": "Targeting YAP/TEAD signaling disturbs RNA polymerase II activity and enhances immunotherapy response via activated cytosolic DNA sensing pathway in gastroesophageal cancer", "abstract_text": "Gastroesophageal adenocarcinoma (GEAC) is a significant global cancer burden. Our previous studies demonstrated that YAP/TEAD are highly expressed in GEAC, and play a critical role in tumor progression, therapy resistance and metastasis. Thus, targeting YAP/TEAD signaling presents a promising therapeutic strategy. Here, we tested a novel YAP/TEAD inhibitor VT00278, a chemical analog of CA3, and showed that VT00278 strongly downregulated YAP/TEAD transcriptional activity, and potently suppressed tumor-promoting phenotypes including proliferation, invasion, tumor sphere formation; induced apoptosis and inhibited tumor growth in vivo especially in radiation resistant FLO-1 XTR GEAC cells. Mechanistically, in addition to impairing YAP/TEAD signaling, VT00278 or YAP depletion repressed RNA polymerase II (RNAPII) transcriptional regulators, reduced RNAPII S2 phosphorylation and decreased anti-apoptosis MCL-1 expression. More interestingly, VT00278 strongly induced DNA damage, activated cytosolic DNA sensing pathway, upregulated innate immune genes (e.g., INFβ) and PD-L1 expression. In a syngeneic mouse model, combining VT00278 with anti-PD-1 therapy strongly inhibited tumor growth, increased CD3+ and CD8+ T cell infiltration, and induced the production of INFγ from CD3 and CD8 cells. These findings support VT00278 as a promising candidate for GEAC treatment, either alone or in combination with immunotherapy.", "source_company": "Coriell Institute for Medical Research", "source_org_type": "研究机构", "row_number": 830, "target_meta": "not available", "MOA_meta": "抑制剂"}, {"drug_name": "BE2K", "company": "City of Hope Comprehensive Cancer Center", "org_type": "医院", "target": "HPV LCR promoter", "modality": "mRNA", "importance_level": "中", "total_score": 55.5, "institution_score": 35, "track_score": 75, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "BE2K通过mRNA-LNP递送靶向HPV LCR启动子，实现表观遗传沉默E6/E7 oncogenes，恢复p53/Rb通路并诱导凋亡。机构为医院研究性质得分较低，但mRNA+新型基因疗法针对HPV癌症未满足需求+PDX模型有效性使其赛道与里程碑具备较好潜力。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8568", "id": "B1XM_5wBX1NQZOEH-LS6", "source_drug_name": "BE2K", "title": "A novel viral-derived epigenetic gene therapy delivered via mRNA-lipid nanoparticles to inhibit HPV-associated malignancies", "abstract_text": "Human Papillomavirus (HPV) is associated with a range of malignancies, including oropharyngeal, cervical, and anal carcinomas. Approximately 47,000 carcinoma cases annually in USA are attributed to HPV causing significant morbidity and mortality. Integration of the episomal HPV genome into the host’s DNA is a critical event in oncogenesis. HPV’s long control region (LCR) promoter overexpresses the viral E6 and E7 proteins, which inhibit the tumor suppressors p53 and Rb1 respectively, driving the oncogenic transformation. E6 and E7 are also critical for tumor maintenance by creating a state of 'oncogene addiction', making them ideal targets for therapeutic intervention. They are considered undruggable, but they present ideal targets for gene therapy interventions. However, gene therapies face significant challenges such as targeting multiple HPV oncogenes within sequence-diverse high-risk HPV subtypes. To this end, we have exploited a viral self-regulatory genetic circuit to develop a compact, single component epigenetic repressor (BE2K). BE2K targets highly conserved sites in the LCR which can silence multiple oncogenes simultaneously in virtually all HPV subtypes. BE2K inhibited the proliferation of high-risk HPV16 and HPV18-associated oropharyngeal, cervical, and anal cancer cell lines. BE2K had no effect on non-HPV associated cell lines. BE2K suppressed E6 and E7 expression resulting in reactivation of the p53 tumor suppressor and caspase-mediated apoptosis. Global mRNA profiling confirmed E6 and E7 reduction, an increase in p53 signaling and apoptosis pathways, as well as a reduction in the E2F transcription factor targets, downstream of Rb1. Of note, an upregulation in interferon pathways and inflammatory response was observed, which may additionally contribute to the anti-proliferative effects in HPV-associated cancers in an immune-competent context. To deliver BE2K intratumorally, it was formulated as mRNA in MC3 lipid nanoparticles (LNPs). An HPV-associated head and neck SCC154 xenograft model in NSG mice was used and LNP-mRNA BE2K reduced tumor volume and improved clinical scores in the mice compared to controls. Immunohistochemistry showed an elevated p53 with a reduction in the Ki-67. Safety profiling showed no effect on serum ALT/AST levels, or liver and spleen histology. To validate our findings, a patient-derived xenograft (PDX) model was established from a primary tonsil HPV-associated head and neck squamous cell cancer. Preliminary experiments in the PDX showed that BE2K treatment resulted in a correlation between tumor growth inhibition and p53 and caspase-3 activation. Overall, BE2K, as a scalable LNP-mRNA formulation, represents a promising new epigenetic mRNA treatment towards a more generalizable gene therapy for HPV-associated malignancies.", "source_company": "City of Hope Comprehensive Cancer Center", "source_org_type": "医院", "row_number": 835, "target_meta": "HPV", "MOA_meta": "其他"}, {"drug_name": "LACO-Stim armored mesothelin-targeted CART therapy", "company": "Peking University Cancer Hospital & Institute", "org_type": "医院", "target": "mesothelin", "modality": "CAR", "importance_level": "中", "total_score": 55.5, "institution_score": 40, "track_score": 75, "milestone_score": 60, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "药物为LACO-Stim加持的靶向mesothelin的CAR-T疗法，靶点明确为mesothelin，modality属热门细胞治疗赛道但固瘤挑战大。机构为国内知名肿瘤医院而非头部药企，处于Phase I临床阶段初步安全性和疗效数据，整体开发潜力中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/12013", "id": "bZ7ECZ0BZznHJdntvNYd", "source_drug_name": "LACO-Stim armored mesothelin-targeted CART therapy", "title": "Safety and preliminary efficacy of a novel LACO-Stim armored mesothelin-targeted CART therapy in advanced solid tumors", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Peking University Cancer Hospital & Institute", "source_org_type": "医院", "row_number": 862, "target_meta": "MSLN", "MOA_meta": "其他"}, {"drug_name": "KRAS G12C inhibitor", "company": "University of North Carolina at Chapel Hill", "org_type": "大学", "target": "KRAS G12C", "modality": "inhibitor", "importance_level": "中", "total_score": 55.5, "institution_score": 35, "track_score": 90, "milestone_score": 45, "field_heat_score": 85, "bonus_score": 0, "brief_reason": "针对KRAS G12C的inhibitor属于RAS领域最热门靶点和赛道之一，但研发机构为大学，开发阶段停留在preclinical机制研究和组合策略探索，无明确临床里程碑。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/345", "id": "vlXM_5wBX1NQZOEH-LS6", "source_drug_name": "KRAS G12C inhibitor", "title": "Combination therapies to enhance RAS inhibitor efficacy: Thinking outside the box", "abstract_text": "The perception that KRAS is undruggable was shattered with the recent approval of two KRAS G12C inhibitors for the treatment of non-small cell lung and colorectal cancers. This success has spurred extensive drug development efforts, with currently over 60 RAS inhibitors targeting essentially all RAS mutations under evaluation in over 170 active clinical trials. However, limited objective response rates and median overall survival highlight the impact of intrinsic and acquired resistance in limiting clinical efficacy. Preclinical experimental studies and genetic analyses of relapsed patients have identified a diverse spectrum of genetic, signaling and cell state mechanisms that drive resistance. Our studies focus on the most KRAS-addicted cancer type, pancreatic ductal adenocarcinoma. We validated the ERK MAPK cascade as a central driver of RAS inhibitor resistance and the MYC transcription factor as the major mechanistic basis of ERK-dependent cancer growth. We also validated the Hippo YAP/TAZ-TEAD and KEAP1-NRF2 transcriptional programs as key contributors to RAS inhibitor resistance. To define the mechanistic basis for resistance, we have profiled ERK, MYC, TEAD and KEAP1-NRF2 regulated transcription and phosphoprotein programs and applied CRISPR-based loss-of-function screens to identify molecular mechanisms of RAS inhibitor resistance. Our studies validated combination strategies focused on orthogonal processes distinct from the RAS signaling network. These include inhibition of the TEAD transcription factor, the AXL receptor tyrosine kinase, and the PRMT5 protein arginine methyltransferase. We also identified two approaches targeting mitochondrial function, blocking glutamine-dependent processes or activation of the ClpP mitochondrial protease. In summary, our studies support the potential therapeutic value of combinations that target processes orthogonal to but converge on the RAS signaling network.", "source_company": "University of North Carolina at Chapel Hill", "source_org_type": "大学", "row_number": 972, "target_meta": "KRAS G12C", "MOA_meta": "抑制剂"}, {"drug_name": "a potent and selective PPIL4 degrader", "company": "St. Jude Children's Research Hospital", "org_type": "医院", "target": "PPIL4", "modality": "degrader", "importance_level": "中", "total_score": 55.5, "institution_score": 45, "track_score": 80, "milestone_score": 40, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "药物为靶向PPIL4的Cereblon依赖degrader，PPIL4作为新兴靶点且degrader模态在TPD领域热度高，但机构为医院/研究型非商业实体、摘要未披露具体数据导致开发阶段和里程碑价值判断较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11314", "id": "RJ7M_5wBZznHJdnt_W3O", "source_drug_name": "a potent and selective PPIL4 degrader", "title": "Identification of a potent and selective PPIL4 degrader with therapeutic potential from a library of Cereblon modulators", "abstract_text": "Abstract is embargoed at this time.", "source_company": "St. Jude Children's Research Hospital", "source_org_type": "医院", "row_number": 996, "target_meta": "PPIL4", "MOA_meta": "降解剂"}, {"drug_name": "monoclonal antibody against EGFL6", "company": "UT MD Anderson Cancer Center", "org_type": "医院", "target": "EGFL6", "modality": "monoclonal antibody", "importance_level": "中", "total_score": 55.5, "institution_score": 35, "track_score": 75, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "靶向EGFL6的单抗通过阻断其促进MHC-I降解的作用，恢复肿瘤免疫原性并增强CD8+ T细胞抗肿瘤效应，在卵巢癌模型中显示显著免疫治疗增敏潜力。机构为顶级癌症中心但非商业公司导致机构分较低，EGFL6为新兴免疫调控靶点且机制新颖但仍处preclinical阶段，总分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5314", "id": "Wp7M_5wBZznHJdnt_W3O", "source_drug_name": "monoclonal antibody against EGFL6", "title": "Reprogramming tumor immunogenicity by targeting EGFL6 in ovarian cancer", "abstract_text": "Ovarian cancer remains the most lethal gynecologic malignancy, and current therapeutic options beyond surgery and chemotherapy provide only modest benefit. Although immune checkpoint inhibitors (ICIs) have transformed treatment for several cancer types, their efficacy in ovarian cancer is limited, partly due to downregulation of Major Histocompatibility Complex class I (MHC-I) that impairs antigen presentation and CD8⁺ T cell-mediated tumor control. Emerging evidence suggests that epidermal growth factor-like protein 6 (EGFL6), produced by cancer-associated fibroblasts and malignant epithelial cells, promotes tumor progression and immune evasion; however, its role in tumor immunogenicity remains unclear. To address this gap, we quantified surface MHC-I by flow cytometry following EGFL6 knockdown using lentiviral shRNA, with efficiency validated by western blotting. Protein abundance and signaling changes were assessed by SDS-PAGE and immunoblotting. Functional consequences were evaluated in co-culture assays with activated OT-I CD8⁺ T cells to measure cytotoxicity and cytokine production. We found that EGFL6 expression inversely correlates with immune infiltration in human ovarian tumors, with EGFL6-high tumors exhibiting a 30-50% reduction in CD8⁺ T-cell density. Therapeutic blockade of EGFL6 using a monoclonal antibody significantly enhanced antitumor immunity in ID8 and KPCA ovarian cancer models in C57BL/6 mice, increasing intratumoral CD8⁺ T-cell infiltration by ~1.5-fold and elevating granzyme B⁺ and IFN-γ⁺ CD8⁺ T-cell frequencies. Mechanistically, EGFL6 promoted internalization and lysosomal degradation of surface MHC-I, reducing H-2Kᵇ/H-2Dᵇ or HLA-A/B/C expression by 40-60% in mouse and human ovarian cancer cells. EGFL6 knockdown or antibody blockade restored MHC-I stability, resulting in a ~2-fold increase in surface MHC-I and improved CD8⁺ T cell-mediated tumor recognition. These findings identify EGFL6 as a previously unrecognized regulator of tumor immunogenicity and provide strong preclinical rationale for combining EGFL6 inhibition with immunotherapeutic strategies in ovarian cancer.", "source_company": "UT MD Anderson Cancer Center", "source_org_type": "医院", "row_number": 1012, "target_meta": "EGFL6", "MOA_meta": "单抗"}, {"drug_name": "DLL3-targeted T-cell engager", "company": "ICE Bioscience", "org_type": "公司", "target": "DLL3", "modality": "TCE", "importance_level": "中", "total_score": 55.5, "institution_score": 45, "track_score": 85, "milestone_score": 40, "field_heat_score": 75, "bonus_score": 0, "brief_reason": "药物为针对DLL3的T-cell engager（TCE），DLL3在高分级神经内分泌肿瘤中高表达，是实体瘤TCE热门靶点；ICE Bioscience作为国内CRO服务商而非原创新药公司，机构分较低，但TCE赛道+DLL3靶点热度高，摘要展示高通量平台下的preclinical活性，整体中等重要性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5129", "id": "cp7M_5wBZznHJdnt_W3O", "source_drug_name": "DLL3-targeted T-cell engager", "title": "A high-throughput luciferase cancer cell panel driving DLL3-targeted TCE discovery", "abstract_text": "Background: T-cell engagers (TCEs) have rapidly moved into the spotlight as a next-generation immunotherapy, lauded for their (1) “off-the-shelf” convenience, (2) dual-arm precision that re-directs, rather than re-engineers, a patient’s own T cells, and (3) capacity to deliver deep, durable responses even after conventional checkpoint blockade has failed. Solid-tumor TCE development is now a major frontier, yet conventional assays—confined to few cell lines—offer limited throughput and cannot probe the full antigen expression spectrum, leaving a blind spot for candidate triage. To close this gap, we selected delta-like ligand 3 (DLL3)—an embryonic Notch inhibitor that is transcriptionally resurrected in high-grade neuroendocrine tumors yet absent from normal adult tissues—and constructed a fully integrated discovery platform anchored by a 20-member luciferase-reporter tumor panel that systematically recapitulates clinically relevant expression gradients.\nMethods: The platform merges four modules: (1) biophysical profiling via SPS binding kinetics and cell-based affinity screens; (2) parallel 2-D/3-D tumor co-culture assays as well as ICI combination to evaluate T-cell mediated cytotoxicity; (3) multiparametric T-cell activation readouts (CD69/CD25, proliferation); and (4) 10-plex cytokine release assays to map safety-relevant inflammatory signatures.\nResults Here we showcase several DLL-3 targeting TCEs using a diverse luciferase-neuroendocrine cell panel. Preclinical studies demonstrate their binding, activation, antitumor activity, and T cell expansion in DLL3+ cell lines across cancer types, juxtaposed with a diminished impact on DLL3- cell lines.\nConclusions: This platform enables high-throughput evaluation of TCEs across the full antigen expression spectrum, systematically linking target density to therapeutic activity and safety outcomes. By linking target density to TCE performance, this system guides candidate selection and accelerates solid-tumour TCE development, while being readily adaptable to other antigens.", "source_company": "ICE Bioscience", "source_org_type": "公司", "row_number": 1026, "target_meta": "DLL3", "MOA_meta": "其他"}, {"drug_name": "anti-PLXNB2 monoclonal antibodies", "company": "Northwestern University", "org_type": "大学", "target": "PLXNB2", "modality": "monoclonal antibody", "importance_level": "中", "total_score": 55.5, "institution_score": 35, "track_score": 75, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "靶点PLXNB2为新型CTC簇形成驱动因子，通过与SEMA4C/SEMA4A结合促进同型和异型簇形成，阻断可抑制乳腺癌转移；大学机构preclinical阶段筛选并AI优化106株抗体显示功能阻断活性，赛道为肿瘤转移新靶点+抗体干预具一定热度。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4574", "id": "p57M_5wBZznHJdnt_W3O", "source_drug_name": "anti-PLXNB2 monoclonal antibodies", "title": "Computational ranking-guided discovery of Plexin-B2 as a driver of circulating tumor cell clusters and AI-facilitated neutralization to prevent and inhibit metastasis", "abstract_text": "Our previous studies and other works demonstrate that multicellular circulating tumor cell (CTC) clusters are up to 50 times more efficient than single CTCs in mediating viable metastasis (Cancer Discovery, 2018, 2023). Yet, the molecular targets underlying this phenomenon and the CTC cluster interactions with immune cells remain poorly understood. To uncover key mediators of CTC clustering and metastatic progression, we developed a computational ranking pipeline integrating adhesion network analysis and metastasis-free survival modeling. This analysis prioritized Plexin-B2 (PLXNB2) as a top-ranked transmembrane protein associated with poor distant metastasis-free survival and enriched expression in CTC clusters from patients with advanced breast cancer. Functional studies demonstrated that loss of PLXNB2 (Plxnb2) markedly reduces both homotypic tumor-tumor and heterotypic tumor-myeloid (monocyte) cluster formation, thereby suppressing spontaneous metastasis in vivo. Mechanistically, PLXNB2 engages SEMA4C on tumor cells and SEMA4A on myeloid cells to drive intercellular adhesion and metastatic colonization. Integrative proteomic and pathway network analysis further identified downstream PLXNB2 signaling effectors regulating cell adhesion and stemness plasticity, corroborating its importance as a central hub for clustering. To therapeutically block PLXNB2 functions in metastasis, we obtained 106 anti-PLXNB2 monoclonal antibodies (mAbs) for functional screening and optimization, both computationally and experimentally. Using artificial intelligence (AI)-driven structural platforms and language models, we assessed the IgG binding and neutralizing possibilities in clustering and proliferation assays. Experimental screen of top candidates revealed that several antibodies effectively disrupted both homotypic tumor-tumor and heterotypic tumor-monocyte clustering. Furthermore, we implemented an AI-guided structural modeling workflow to predict the PLXNB2-IgG complex, identify active binding residues, and optimize antibody-antigen energetics for enhanced affinity and neutralization. Together, these findings identify PLXNB2 as a key molecular regulator of CTC clustering and metastatic seeding and establish a framework for structure-guided antibody engineering to therapeutically target CTC cluster-driven breast cancer metastasis.", "source_company": "Northwestern University", "source_org_type": "大学", "row_number": 1065, "target_meta": "PLXNB2", "MOA_meta": "单抗"}, {"drug_name": "PARG inhibitors", "company": "University of Bern", "org_type": "university", "target": "PARG", "modality": "inhibitor", "importance_level": "中", "total_score": 55.5, "institution_score": 35, "track_score": 75, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "PARG抑制剂作为PARP抑制剂毒性救援策略，通过改善治疗窗增强PARPi在HR缺陷肿瘤中的疗效。大学机构得分较低，但PARG作为新兴靶点结合毒性缓解机制具有一定创新性和赛道潜力，整体处于中等重要性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4631", "id": "u57M_5wBZznHJdnt_W3O", "source_drug_name": "PARG inhibitors", "title": "Expanding the therapeutic window of PARP inhibitors by co-administering PARG inhibitors", "abstract_text": "Background:\nHomologous recombination (HR) deficiency sensitizes tumors to PARP inhibitors (PARPi), which are standard-of-care for HR-deficient cancers. Despite their efficacy, clinical use of PARPi is limited by on-target toxicity, particularly anemia, leading to dose reductions and drug holidays in about half of treated patients. To address these limitations and expand the therapeutic window of PARPi, we investigated co-administration with selective PARG inhibitors (PARGi).\nMethods:\nCell survival assays were used to evaluate the interaction between potent PARP inhibitors (talazoparib, saruparib), less potent PARP inhibitors (niraparib, olaparib, rucaparib), and selective PARG inhibitors in HR-deficient cell lines. Bone marrow toxicity was assessed in mice and rats treated with talazoparib (0.2-0.25 mg/kg) or saruparib (0.1 mg/kg), administered alone or in combination with selective PARG inhibitors undergoing clinical development, using a 4-days-on/2-days-off/4-days-on regimen. Red blood cell counts, hematocrit, and body weight were measured one day after treatment. Antitumor efficacy was evaluated in DLD1-BRCA2-knockout cell line-derived xenografts (CDX) using a 3-days-on/4-days-off dosing schedule, administered alone or in combination with PARG inhibitors.\nResults:\nIn cell survival assays, PARG inhibitors did not antagonize the cytotoxicity of potent PARPi in HR-deficient cells. In vivo, PARPi monotherapy induced anemia, weight loss, and mortality. Co-administration of PARG inhibitors rescued anemia, attenuated weight loss, and prevented treatment-related deaths. CDX studies demonstrated that tumor growth inhibition by PARPi was maintained or enhanced in combination with PARG inhibitors, allowing higher PARPi dosing without compromising safety. In rats, anemia induced by PARPi was similarly rescued by a PARG inhibitor. Overall, the combination improved the therapeutic window, enabling enhanced efficacy at higher PARPi doses.\nConclusions:\nPARG inhibition selectively mitigates PARPi-induced toxicity without compromising anticancer efficacy in HR-deficient tumors, thereby expanding the therapeutic window. This approach enables higher PARPi dosing for improved tumor control or equivalent efficacy with fewer adverse events, particularly anemia. By reducing PARPi-associated toxicity, PARG inhibition may also facilitate combination therapies, warranting further investigation.", "source_company": "University of Bern", "source_org_type": "大学", "row_number": 1084, "target_meta": "PARG", "MOA_meta": "抑制剂"}, {"drug_name": "YS207", "company": "The University of Texas MD Anderson Cancer Center", "org_type": "医院", "target": "TrxR1", "modality": "other", "importance_level": "中", "total_score": 55.5, "institution_score": 35, "track_score": 75, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 5, "brief_reason": "YS207为首创的TrxR1共价异双功能DUBTAC抑制剂，通过稳定共价抑制TrxR1显著提升ROS水平，展现新型抗肿瘤机制。机构为顶级癌症医院但非商业药企、赛道为新兴DUBTAC+ROS调控热点、仅preclinical阶段但有体外/体内活性及模型数据，故综合重要性中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5681", "id": "vZ7M_5wBZznHJdnt_W3O", "source_drug_name": "YS207", "title": "Discovery of a novel, covalent and heterobifunctional thioredoxin reductase inhibitor with antitumor activity", "abstract_text": "Reactive oxygen species (ROS) play a central role in cellular signaling and homeostasis. However, imbalances in ROS levels contribute to various pathologies, including cancer. Tumor cells often upregulate antioxidant systems, such as the thioredoxin reductase (TrxR) and glutathione (GSH) pathways, to buffer against oxidative stress. The identification of aberrant metabolism and ROS has generated excitement and promise as a hallmark targetable vulnerability of tumors. Unfortunately, despite tremendous academic and industry efforts, this promise remains unfulfilled. Here, we report the discovery of YS207, a first-in-class covalent heterobifunctional inhibitor of TrxR1 using the deubiquitinase-targeting chimera (DUBTAC) technology. YS207 is composed of TrxR1 recruiting moiety coupled to deubiquitinase recruiting moiety via a novel chemical linker resulting in stabilization of covalently inhibited TrxR1 for profound generation of therapeutic levels of ROS. YS207 treatment potently inhibited TrxR1 enzymatic activity in vitro and in vivo (IC50 of 40nM & 700nM respectively). Mechanistically, YS207 elevated ROS levels, induced lipid peroxidation, and decreased intracellular GSH. Additionally, we observed profound alterations of the mitochondria including swelling, loss of cristae, increased electron density and prominent mitophagy, all characteristic of oxidative damage by using transmission electron microscopy (TEM). Rescue experiments with the ROS scavenger N-acetyl cysteine (NAC) confirmed that YS207-induced cell death was ROS-dependent. Large-scale PRISM profiling across 885 cancer cell lines revealed that sensitivity to YS207 strongly correlates with TrxR1 dependency, NADPH metabolism, and selenoprotein biosynthesis pathways. Notably, dual knockout of TrxR1 and GPX4 partially rescued YS207-induced cytotoxicity, underscoring a cooperative role in redox regulation. Further, we showed promising anti-tumor growth inhibitory activity of YS207 in xenograft models of lung cancer. Taken together, our results demonstrate that YS207 is a potent ROS modulator with potential antitumor activities through novel mechanism of action. We aim to pursue further development of this class of molecules in tumors with enhanced vulnerability to redox imbalance.", "source_company": "The University of Texas MD Anderson Cancer Center", "source_org_type": "医院", "row_number": 1086, "target_meta": "TrxR", "MOA_meta": "其他"}, {"drug_name": "CDK2 inhibitors", "company": "University of Colorado Denver School of Medicine", "org_type": "大学", "target": "CDK2", "modality": "inhibitor", "importance_level": "中", "total_score": 55.5, "institution_score": 30, "track_score": 85, "milestone_score": 65, "field_heat_score": 80, "bonus_score": 2, "brief_reason": "靶点为CDK2，机制聚焦于Cyclin E1驱动卵巢癌中p16高表达导致对CDK2抑制剂敏感，可作为潜在生物标志物。机构为大学非商业实体得分较低，但CDK2抑制剂赛道热度高（克服CDK4/6耐药、热门细胞周期靶点）、临床多款药物在研且卵巢癌潜在需求强，得分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1498", "id": "y57M_5wBZznHJdnt_W3O", "source_drug_name": "CDK2 inhibitors", "title": "Mechanisms of sensitivity and resistance to CDK2 inhibitors", "abstract_text": "CDK2 is a core cell-cycle kinase that phosphorylates many substrates to drive progression through the cell cycle. We used several CDK2 inhibitors in clinical development to interrogate CDK2 substrate phosphorylation, cell-cycle progression, and drug adaptation in preclinical models. Whereas CDK1 is known to compensate for loss of CDK2 in Cdk2-/- mice, this is not true for acute inhibition of CDK2. In normal mammary cells and estrogen receptor-positive breast cancer cells, CDK2 inhibition causes a rapid loss of substrate phosphorylation that is rapidly restored by a hard-wired cell-cycle buffering mechanism in which CDK4/6 maintains Rb hyper-phosphorylation, E2F transcriptional activity, and Cyclin A2 expression, enabling re-activation of CDK2. Thus, we hypothesized that sensitivity to CDK2 inhibition is linked to the absence of this CDK4/6-mediated compensatory mechanism. Indeed, we found that Cyclin E1-driven ovarian cancers often co-express the tumor suppressor p16, which inhibits CDK4/6. We show that ovarian cancer cells expressing p16 exhibit heightened sensitivity to CDK2 inhibitors and that depletion of p16 renders them resistant. Multiplexed immunofluorescence of 225 ovarian patient tumors reveals that at least 18% of tumors express high Cyclin E1 and high p16, a group that we expect to be particularly sensitive to CDK2 inhibition. These data further reveal two cell-cycle entry paths that are readily detectable in patient tumors - the canonical CDK4/6-Cyclin D path, and the CDK2-Cyclin E path ‘bypass’ path. Thus, p16 may be a useful biomarker for identifying the patients that are most dependent on the CDK2-Cyclin E path and are thus most likely to benefit from CDK2 inhibitors.", "source_company": "University of Colorado Denver School of Medicine", "source_org_type": "大学", "row_number": 1095, "target_meta": "CDK2", "MOA_meta": "抑制剂"}, {"drug_name": "IL7-IL15-iMSCs", "company": "UT MD Anderson Cancer Center", "org_type": "医院", "target": "未披露", "modality": "other", "importance_level": "中", "total_score": 55.5, "institution_score": 35, "track_score": 75, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "IL7-IL15-iMSCs为工程化iPSC来源的间充质基质细胞，通过分泌IL-7和IL-15重塑免疫抑制性肿瘤微环境为免疫激活状态，机制新颖且具转化潜力。机构为顶级肿瘤医院但非产业化药企导致institution_score较低，赛道为细胞治疗+细胞因子工程较热，preclinical数据扎实且多瘤种有效，总体重要性中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9637", "id": "8p7M_5wBZznHJdnt_W3O", "source_drug_name": "IL7-IL15-iMSCs", "title": "Engineered IL7/IL15 secreting iPSC-derived mesenchymal stromal cells convert the immunosuppressive into immune-activated tumor microenvironments (TME) and potentiate antitumor immunity", "abstract_text": "Mesenchymal stromal cells (MSCs) derived from bone marrow (BM-MSCs) exhibit inherent tumor-tropic behavior (Andreeff M., Cancer Res. 2002, JNCI 2004). However, their finite proliferative lifespan, donor-to-donor variability, and senescence-associated transcriptional drift present barriers to clinical scalability. To address these limitations, we reprogrammed adult dermal fibroblasts into induced pluripotent stem cells (iPSCs) using a synthetic, non-integrating mRNA transfection system. These iPSCs were stably modified to express interleukin-7 and interleukin-15, prior to mesodermal lineage specification into MSCs (hereafter referred to as IL7-IL15-iMSCs). Flow cytometry and transcriptomic profiling confirmed expression of canonical MSC markers (CD73⁺CD90⁺CD105⁺), absence of hematopoietic or endothelial lineage antigens and trilineage differentiation potential. IL7-IL15-iMSCs secreted supraphysiologic levels of cytokines, converting immune-suppressive MSCs into immune-activating MSCs. In vitro, IL7-IL15-iMSCs induced potent T cell proliferation sustaining the long-term expansion of T cells, macrophages and CAR T cells in vitro, and induced tumor cell death in a triple co-culture system comprising IL7-IL15-iMSCs, the ovarian cancer cell line ID8, and human PBMCs. In a syngeneic mouse model of ovarian cancer (ID8 and platinum-resistant ID8 cells in C57BL/6 mice), intraperitoneal administration of IL7-IL15-MSCs resulted in reduced tumor burden and extended survival. Immunohistochemical and CyTOF analyses revealed massive infiltration of activated T cells, macrophages, and other immune cells into the tumor microenvironment (TME) as well as enrichment in tumoricidal M1-type macrophages, with no detection of exhausted or regulatory T cells, in contrast to controls. To mitigate pulmonary first-pass entrapment associated with systemic, intra-venous (IV) MSC delivery, we optimized a fractionated low-dose IV administration regimen in the orthotopic 4T1 triple-negative breast cancer model. Six weeks post IL7-IL15-iMSC IV administration, tissue IHC staining showed robust iMSC localization to the TME, infiltration of immune cells and tumor reduction as observed in ovarian cancer.\nConclusion: These data establish IL7-IL15-iMSCs as a novel, immunologically active stromal cell platform capable of remodeling the TME and amplifying both innate and adaptive anti-tumor responses. IL7-IL15 iMSC convert an immune-suppressed into an immune-activated TME in diverse tumor types. The scalability of iPSC-derived MSCs, combined with synthetic mRNA reprogramming and stable cytokine expression, supports the suitability of this platform for clinical translation. A first clinical trial in ovarian cancer is under development.", "source_company": "UT MD Anderson Cancer Center", "source_org_type": "医院", "row_number": 1119, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "POLQi", "company": "Sheba Medical Center", "org_type": "医院", "target": "POLQ", "modality": "inhibitor", "importance_level": "中", "total_score": 55.5, "institution_score": 30, "track_score": 85, "milestone_score": 60, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "POLQi为POLQ抑制剂，与PARPi联用在BRCA突变PDAC模型中显示延长应答时间、延缓耐药的趋势，具有合成致死潜力。机构为医院而非药企导致institution_score较低，但POLQ抑制剂赛道在HRD肿瘤中热度高、机制新颖，preclinical PDX模型数据较扎实。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3999", "id": "JJ7M_5wBZznHJdnt_W7O", "source_drug_name": "POLQi", "title": "Antitumor activity of PARPi and POLQi combination therapy in a BRCA-mutated PDAC model", "abstract_text": "Pancreatic ductal adenocarcinoma (PDAC) is one of the deadliest cancers. BRCA1/2-mutated PDAC is a unique subgroup with exceptional responses to platinum chemotherapy/PARP inhibition (PARPi). A spectrum of responses is observed, from refractory to long term-remission Despite this promising strategy, most patients develop resistance. Inhibition of DNA-polymerase theta (POLQ), a key component in DNA-repair, may further sensitize cancer cells to platinum/PARPi in combination with a PARP1-selective (AZD5305/saruparib) or non-selective PARP inhibitor (olaparib). We conducted a long-term in vivo experiment testing PARPi and POLQi combination utilizing a platinum-sensitive, BRCA2 mutated PDAC PDX model to investigated the potential to prolong response and reduce resistance. Simultaneously, this combination was tested in accordance to the maintenance approach in clinical setting: a cisplatin induction followed by maintenance PARPi, POLQi and their combinations. A total of 159 tumor-bearing mice were randomized to: vehicle control; olaparib; saruparib; POLQi; saruparib+POLQi; olaparib+POLQi, and maintenance treatment groups by cisplatin induction for four weeks followed by switch to: vehicle control; POLQi, saruparib and saruparib+POLQi (n=8-19/group). POLQi alone had no effect on tumor growth. Both PARPi (olaparib/saruparib) monotherapies significantly delayed tumor growth, with saruparib displaying a trend towards prolonged effect vs olaparib (saruparib 69% complete responders (CR) vs control p=0.0014; olaparib 47% CR vs control p=0.0052). Combination therapy of olaparib and POLQi also showed a trend towards extended duration of response compared to olaparib monotherapy (olaparib vs control p=0.005; olaparib+POLQi vs control p=0.00017). Acquired resistance developed in seven mice (22%) with PARPi monotherapy (olaparib n=4, saruparib n=3) and was only seen in five (13%) mice in combination therapy with POLQi (saruparib+POLQi n=3; olaparib+POLQi n=2). In the maintenance study, cisplatin induction initiated a strong anti-tumor effect that was not maintained after switching to vehicle (22% CR by end of study). Addition of saruparib maintenance alone or in combination with POLQi significantly extended the duration of responses (60-70% CR by end of study). Our pre-clinical in vivo data indicate that 1) saruparib displayed a trend towards increased efficacy vs olaparib; 2) combined PARPi and POLQi therapy showed a trend towards extending the duration of response and delaying resistance; 3) cisplatin induction produced a strong antitumor effect which remained with maintenance PARPi±POLQi. Tumors with acquired resistance are undergoing extensive molecular analyses to determine the mechanisms of resistance.This preclinical study enables further understanding and investigation of this unique subtype with the aim to develop alternative treatments to prevent acquisition of resistance.", "source_company": "Sheba Medical Center", "source_org_type": "医院", "row_number": 1148, "target_meta": "POLQ", "MOA_meta": "抑制剂"}, {"drug_name": "AML874", "company": "Institute for Research in Immunology and Cancer (IRIC)", "org_type": "研究机构", "target": "CDK8/CDK19", "modality": "inhibitor", "importance_level": "中", "total_score": 55.5, "institution_score": 35, "track_score": 75, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 2, "brief_reason": "AML874为CDK8/CDK19抑制剂，靶向Mediator complex，在AML尤其是FLT3突变亚型中显示活性，并与venetoclax有显著协同作用。研究机构背景拉低机构分，但新型靶点+preclinical体内协同数据支撑中等赛道与里程碑热度，总分处于中偏上水平。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11126", "id": "QZ7M_5wBZznHJdnt_W7O", "source_drug_name": "AML874", "title": "Synergistic targeting of Mediator complex and BCL-2 reveals a novel therapeutic strategy for acute myeloid leukemia", "abstract_text": "Background: Acute myeloid leukemia (AML) is a heterogeneous and aggressive hematologic malignancy characterized by the uncontrolled proliferation of myeloid stem and progenitor cells. Despite therapeutic advances, the 5-year survival rate remains low, underscoring the urgent need for novel therapeutic strategies.\nMethods: To meet this need and identify new anti-leukemic agents, we conducted a high-throughput cell viability screen of 10,000 small molecules using 56 different primary AML specimens of diverse genetic anomalies. Molecules showing highly correlated inhibition profiles were grouped into 21 compound correlation clusters (CCCs). The overall hypothesis was that compounds sharing highly correlated inhibition profiles most likely act on the same biological pathway / molecular target. Among the various CCC identified, CCC163, which include compound AML874, emerged as a potent and selective anti-leukemic hit.\nResults: Integrated pharmacological and CRISPR-Cas9 screening revealed the Mediator complex as the molecular target of AML874. Mechanistic studies confirmed that AML874 inhibits Mediator complex function through CDK8/CDK19 kinase inhibition, leading to transcriptional dysregulation and loss of Mediator structural integrity. Kinase-dead CDK8 rescue assays confirmed that AML874 activity depends on CDK8 kinase function. Notably, FLT3-mutated AML primary specimens exhibited increased sensitivity to AML874, indicating a potential subtype-specific therapeutic opportunity. Structure-activity relationship profiling of AML874 analogs further supported the dependency on Mediator complex disruption for anti-leukemic activity. Finally, combination studies demonstrated strong synergy between AML874 and the BCL2 inhibitor venetoclax both in vitro and in vivo, resulting in markedly improved anti-leukemic activity in xenograft models.\nConclusions: This work identifies the Mediator complex as a novel vulnerability in AML and positions CDK8/CDK19 inhibition, alone or in combination with Venetoclax, as a promising strategy for the development of next-generation targeted therapies for this disease.", "source_company": "Institute for Research in Immunology and Cancer (IRIC)", "source_org_type": "研究机构", "row_number": 1169, "target_meta": "CDK8,CDK19", "MOA_meta": "抑制剂"}, {"drug_name": "USP5 inhibitors", "company": "China Medical University Hospital", "org_type": "医院", "target": "USP5", "modality": "inhibitor", "importance_level": "中", "total_score": 55.5, "institution_score": 35, "track_score": 75, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "靶向USP5的小分子抑制剂，通过恢复MRE11内切酶活性促进肿瘤免疫原性DNA产生及NK细胞介导杀伤，具有增强抗肿瘤免疫的机制创新性。机构为医院导致institution_score偏低，但靶点与免疫逃逸相关机制处于较高热度，preclinical数据较扎实包括PDTO和同系模型疗效。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1356", "id": "YJ7M_5wBZznHJdnt_W7P", "source_drug_name": "USP5 inhibitors", "title": "USP5 suppresses MRE11 endonuclease function to facilitate tumor immune escape", "abstract_text": "Replication stress is a hallmark of cancer that generates abnormal cytosolic DNA, thereby activating intrinsic immune pathways that constrain tumor growth. To survive, malignant cells must counteract these immune surveillance mechanisms, yet the underlying regulatory processes remain incompletely understood. The MRE11 nuclease plays a dual role in maintaining genome stability and processing stalled replication forks, where its endonuclease activity produces single-stranded DNA (ssDNA) capable of activating the cGAS-STING axis to induce anti-tumor immunity. In this study, we uncover a ubiquitin-dependent mechanism that connects DNA replication stress to immune evasion. Loss of tyrosine 211 phosphorylation on PCNA (pY211-PCNA) induces endogenous replication stress and promotes site-specific polyubiquitination of MRE11. This modification enhances MRE11 endonuclease activity, resulting in cytosolic ssDNA accumulation, activation of innate immune signaling, and increased susceptibility to natural killer (NK) cell-mediated cytotoxicity. Conversely, in cells expressing pY211-PCNA, the deubiquitinase USP5 is recruited to replication forks, where it removes ubiquitin from MRE11, thereby attenuating its endonuclease activity and suppressing cytosolic ssDNA formation and immune activation. Clinically, elevated USP5 expression correlates with tumor metastasis and poor prognosis in breast cancer. Genetic ablation or pharmacologic inhibition of USP5 restores MRE11-dependent ssDNA production, promotes NK cell infiltration, and suppresses tumor growth in immune-competent but not immune-deficient mouse models. An unbiased drug screen identified two FDA-approved compounds as potent USP5 inhibitors, which mimic USP5 depletion by enhancing cytosolic ssDNA accumulation, triggering NK- and PBMC-mediated killing of patient-derived tumor organoids (PDTOs), and suppressing tumor growth in syngeneic mouse models. These results identify USP5 as a critical negative regulator of MRE11-driven immunogenic DNA processing and reveal a therapeutic strategy to potentiate anti-tumor immunity through targeted USP5 inhibition.", "source_company": "China Medical University Hospital", "source_org_type": "医院", "row_number": 1187, "target_meta": "USP5", "MOA_meta": "抑制剂"}, {"drug_name": "engineered CAR T cell secreting a protein-based Galectin-3 inhibitor", "company": "University College London (UCL) Cancer Institute", "org_type": "大学", "target": "Galectin-3", "modality": "CAR", "importance_level": "中", "total_score": 55.5, "institution_score": 45, "track_score": 85, "milestone_score": 35, "field_heat_score": 75, "bonus_score": 3, "brief_reason": "通过工程化CAR-T细胞原位分泌蛋白类Galectin-3抑制剂阻断Gal3介导的免疫抑制，提升儿科实体瘤CAR-T疗效。机构为大学导致institution_score偏低，但CAR+新型武装化策略+儿科实体瘤未满足需求使赛道和领域热度较高，目前仅功能验证和在体研究进行中。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5180", "id": "hJ7M_5wBZznHJdnt_W7P", "source_drug_name": "engineered CAR T cell secreting a protein-based Galectin-3 inhibitor", "title": "Galectin-3 blockade reprograms the tumor microenvironment and improves CAR T-cell therapy in pediatric cancers", "abstract_text": "CAR T-cell therapies have revolutionized the treatment of hematological malignancies, yet their efficacy in solid tumors remains limited. Pediatric solid tumors are particularly challenging due to their low mutational burden, scarce T-cell infiltration, and highly immunosuppressive tumor microenvironment (TME). Although CAR T cells can induce initial responses, sustaining durable activity is difficult.\nTo identify mechanisms that could be targeted to enhance CAR T-cell function, we performed scRNA-seq analysis of nearly 100 pediatric tumor samples and characterized the T-cell and myeloid compartments. We found that Galectin-3 (Gal3), an immunosuppressive and protumorigenic molecule, was predominantly expressed by myeloid cells and strongly associated with an M2-like macrophage phenotype. Gal3 expression inversely correlated with overall T-cell infiltration and, more specifically, with the proportion of reactive-like T cells. Spatial imaging confirmed Gal3 protein expression in the TME and showed colocalization with immunosuppressive myeloid of T cell markers\nBased on these findings, we hypothesized that Gal3 inhibition could synergize with CAR T-cell activity by alleviating myeloid-driven immunosuppression. To deliver Gal3 inhibition directly within the TME, we engineered an “armed” CAR T cell that secretes a protein-based Gal3 inhibitor. Functional characterization is ongoing, and in vivo evaluation in pediatric tumor mouse models is currently in progress.\nOur results identify Gal3 as a key barrier to T-cell infiltration and activation in pediatric tumors and provide a strong rationale for combining CAR T-cell therapy with targeted Gal3 inhibition. This engineered CAR T-cell platform represents a promising strategy to enhance therapeutic efficacy in pediatric solid tumors.", "source_company": "University College London (UCL) Cancer Institute", "source_org_type": "大学", "row_number": 1214, "target_meta": "LGALS3", "MOA_meta": "其他"}, {"drug_name": "ENPP-1-IN-1", "company": "Shanghai Chest Hospital", "org_type": "医院", "target": "ENPP1", "modality": "inhibitor", "importance_level": "中", "total_score": 55.5, "institution_score": 30, "track_score": 85, "milestone_score": 60, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "ENPP1抑制剂通过阻断cGAMP水解激活STING通路，逆转EGFR-TKI耐药NSCLC免疫逃逸，在体外和免疫重建小鼠模型中增强抗PD-1疗效。机构为医院非企业研发，赛道热门（STING免疫+耐药肿瘤），但仅preclinical水平。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4939", "id": "iZ7M_5wBZznHJdnt_W7P", "source_drug_name": "ENPP-1-IN-1", "title": "ENPP1 inhibits the cGAS-STING pathway to mediate immune evasion in EGFR-TKI resistant NSCLC", "abstract_text": "Third-generation EGFR tyrosine kinase inhibitors (TKIs), such as osimertinib, have demonstrated promising clinical efficacy in EGFR-mutant non-small cell lung cancer (NSCLC). Despite substantial progress with EGFR-TKIs, the development of acquired resistance remains a major clinical challenge. Notably, the addition of immunotherapy after TKI resistance has not resulted in significant survival benefits compared to chemotherapy. In this study, single-cell RNA sequencing analysis of key immune cell subpopulations and tumor immune features revealed an immunosuppressive shift in the tumor microenvironment of TKI-resistant tumors, characterized by an increased proportion of M2 macrophages, reduced dendritic cells (DCs) and M1 macrophages, and immune function scores indicative of an immunosuppressive state. Comprehensive transcriptomic profiling of established osimertinib-resistant NSCLC cell lines (HCC827OR, H1975OR, PC9OR) demonstrated a significant upregulation of ENPP1 expression compared with their parental, TKI-sensitive counterparts. Given that ENPP1 functions as a cGAMP hydrolase and is implicated in STING pathway suppression and immune evasion, we first assessed cGAMP hydrolysis activity and found that resistant cells exhibited enhanced cGAMP-degrading capacity. Co-culture experiments of tumor cells with antigen-presenting cells (APC) revealed that resistant tumor cells more effectively suppressed cGAS-STING signaling in APCs, thereby attenuating T-cell activation and cytotoxicity. Both genetic silencing of ENPP1 via siRNA and pharmacological inhibition using the ENPP1 inhibitor ENPP-1-IN-1 enhanced STING pathway activation in APCs and restored T-cell activation and cytotoxic functions in co-culture systems. Bioinformatic prediction and dual-luciferase assays identified SP1 as a direct transcriptional regulator of ENPP1. Finally, immune reconstitution mouse models confirmed that ENPP-1-IN-1 potentiated the efficacy of anti-PD-1 therapy in HCC827OR xenografts by increasing immune infiltration and T-cell activity. Collectively, our study highlights a critical role for ENPP1 in mediating immune evasion through suppression of the cGAMP-STING pathway in the EGFR-TKI resistant tumor, supporting ENPP1 as a promising therapeutic target to enhance immunotherapy efficacy in EGFR-TKI resistant NSCLC.", "source_company": "Shanghai Chest Hospital", "source_org_type": "医院", "row_number": 1216, "target_meta": "ENPP1", "MOA_meta": "抑制剂"}, {"drug_name": "anti-PD-1 antibody", "company": "Huazhong University of Science and Technology", "org_type": "大学", "target": "PD-1", "modality": "inhibitor", "importance_level": "中", "total_score": 55.5, "institution_score": 35, "track_score": 75, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "药物为anti-PD-1抗体，靶向PD-1通路，属于成熟免疫检查点抑制剂赛道。研究机构为国内高校，临床前机制研究显示Quad Shot放疗可逆转HNSCC中PD-1抑制剂耐药，具有一定创新性但整体开发阶段较早。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5585", "id": "i57M_5wBZznHJdnt_W7P", "source_drug_name": "anti-PD-1 antibody", "title": "Combined Quad Shot regimen and immunotherapy for incurable recurrent or metastatic head and neck cancer", "abstract_text": "Background: Recurrent/metastatic head and neck squamous cell carcinoma (R/M HNSCC) presents significant therapeutic challenges. Current first-line regimens based on PD-1 inhibitors, either as monotherapy or combined with chemotherapy, demonstrate limited efficacy with objective response rates (ORR) of only 20-40% and median overall survival below 15 months. While the theoretical synergy between radiotherapy and immunotherapy is well-established and has been validated across various malignancies, this promising combination has yet to demonstrate breakthrough success in HNSCC clinical practice. This study investigates the potential of a cyclical hypofractionated palliative radiotherapy regimen (QUAD SHOT) to reverse immunotherapy resistance in R/M HNSCC.\nMethods: We administered palliative Quad Shot radiotherapy to 20 R/M HNSCC patients who had stable disease or progressive disease after two cycles of chemotherapy combined with immunotherapy. These patients received Quad Shot regimen (3.5 Gy twice daily over 2 consecutive days at 4 week intervals per cycle) while maintaining their original systemic treatment. Additionally, in mouse subcutaneous transplantation and spontaneous tumor models, we compared the anti-tumor efficacy of Quad Shot radiotherapy combined with anti-PD-1 antibody versus conventional continuous radiotherapy. Comprehensive immune monitoring utilizing single-cell RNA sequencing and flow cytometry was employed to characterize changes in the tumor microenvironment and tumor-draining lymph nodes.\nResults: Clinical observations revealed that the irradiated lesions in these treatment-resistant patients achieved an ORR of 85% (17/20) following Quad Shot integration, including complete response in 25% (5/20) and partial response in 60% (12/20) of cases. In preclinical models, the Quad Shot regimen demonstrated superior tumor control and survival outcomes compared to conventional radiotherapy. Mechanistic investigations elucidated that the cyclic radiotherapy schedule effectively prevents the transition from immune activation to immunosuppression typically observed after continuous radiotherapy. This modality facilitates periodic clearance of terminally exhausted CD8⁺ T cells within the tumor microenvironment while promoting expansion of T progenitor exhausted (Tpex) cells in draining lymph nodes, thereby enabling replenishment of the intratumoral T-cell repertoire.\nConclusions: The Quad Shot radiotherapy regimen represents a promising strategy for reversing immunotherapy resistance in R/M HNSCC. The core mechanism involves the cyclic radiotherapy pattern reshaping the tumor immune microenvironment, reversing T-cell exhaustion, and promoting the replenishment of stem-like Tpex cells, thereby restoring tumor response to immune checkpoint inhibitors.", "source_company": "Huazhong University of Science and Technology", "source_org_type": "大学", "row_number": 1218, "target_meta": "PD1", "MOA_meta": "抑制剂"}, {"drug_name": "DSPE-PEG2000", "company": "University of Science and Technology of China", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "中", "total_score": 55.5, "institution_score": 35, "track_score": 75, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 4, "brief_reason": "DSPE-PEG2000作为通用BSB调制剂，通过膜锚定PEG瞬时降低抗体-抗原亲和力以改善实体瘤中ADC和双抗的肿瘤渗透和疗效，机制新颖且广适性强。机构为大学得分较低，但赛道涉及热门抗体递送优化且显示明确动物模型优效证据，综合重要性中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4417", "id": "jp7M_5wBZznHJdnt_W7P", "source_drug_name": "DSPE-PEG2000", "title": "A general method to overcome the binding site barrier in antibody-based therapeutics", "abstract_text": "Background: Insufficient intratumoral penetration remains a major limitation of antibody-based therapeutics in solid tumors. The binding site barrier (BSB), driven by high-affinity interactions near perivascular regions, restricts deeper tissue distribution of ADCs and bispecific antibodies and thereby limits their therapeutic index. Current strategies such as co-dosing with parental antibodies or engineering lower-affinity variants are constrained by target specificity and require redesign of each therapeutic. A broadly applicable, novel approaches that transiently modulates BSB without altering antibody structure is needed to improve tumor penetration.\nMethods: We evaluated DSPE-PEG2000, an FDA-approved amphiphilic phospholipid-polymer conjugate, as a general BSB modulator. Using HER2-, TROP2-, and PD-1/VEGF-targeted therapeutics, we quantified changes in cell-surface engagement, receptor accessibility, and internalization across multiple cancer cell models via flow cytometry, confocal microscopy, and live-cell imaging. In subcutaneous xenograft models, we assessed the intratumoral distribution of Cy3-labeled ADCs and a PD-1/VEGF bispecific antibody using longitudinal IVIS imaging and spatial analysis of tumor sections. Antitumor efficacy was evaluated by tumor growth suppression, treatment durability, and survival. Biosafety assessments included serum chemistry and histopathology of major organs.\nResults: DSPE-PEG2000 rapidly incorporated into tumor cell membranes and generated a short-range PEG layer that transiently reduced antibody-antigen interactions by 40-60% across diverse targets (e.g., HER2, TROP2, and PD-1/VEGF). This surface modulation did not impair antibody internalization or downstream trafficking. In vivo, DSPE-PEG2000 substantially broadened the intratumoral distribution of ADCs and bispecific antibodies, enabling deeper penetration beyond perivascular regions. The improved spatial delivery translated into greater tumor growth inhibition and prolonged survival, consistent across multiple ADC payloads and antibody architectures. Co-administration did not increase systemic exposure or off-tumor tissue accumulation, and no treatment-related toxicity was observed.\nConclusions: DSPE-PEG2000 provides a generalizable, target-independent strategy to overcome the binding site barrier and enhance the distribution and functional efficacy of antibody-based therapeutics in solid tumors. By transiently modulating BSB through membrane-anchored PEG grafting without modifying antibody affinity or structure, DSPE-PEG2000 offers a practical and clinically compatible approach to improve tumor penetration of current and next-generation antibody therapeutics.", "source_company": "University of Science and Technology of China", "source_org_type": "大学", "row_number": 1221, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "EGFR/B7H3-ADC (纽迈生物)", "company": "NeoMab Biotechnology Co., Ltd", "org_type": "公司", "target": "EGFR/B7H3", "modality": "ADC", "importance_level": "中", "total_score": 55.5, "institution_score": 45, "track_score": 85, "milestone_score": 35, "field_heat_score": 75, "bonus_score": 3, "brief_reason": "该药为EGFR/B7H3双靶点ADC，靶向热门肿瘤标志物EGFR和B7H3，采用双特异性设计提升肿瘤选择性。机构为国内抗体平台型公司子公司，非头部药企，preclinical阶段仅显示CDX模型优于单靶ADC，赛道ADC+双靶点热度高但早期开发阶段限制总分。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5436", "id": "Lp7M_5wBZznHJdnt_W3O", "source_drug_name": "EGFR/B7H3-ADC (纽迈生物)", "title": "A novel EGFR and B7H3 dual-targeted antibody-drug conjugate (ADC) for the treatment of solid tumors", "abstract_text": "Background: EGFR (also known as HER1) is an epidermal growth factor receptor involved in tumor progression, and its overexpression in approximately 70% of colorectal cancer (CRC), 60% of lung cancers, and over 90% of head and neck squamous cell carcinoma (HNSCC). B7H3 belongs to the B7 immunoregulatory family. B7H3 is overexpressed on a wide range of solid tumors such as lung cancers, gastrointestinal cancers and gynecological cancers, but its expression is absent or low in normal tissues. Therefore, dual targeting of both EGFR and B7H3 can achieve better therapeutical efficacy. EGFR/B7H3-ADCs are novel bispecific Antibody-drug Conjugates (ADCs), composed of fully human anti-EGFR/B7H3 bispecific antibodies (BsAbs) conjugated to TOP1i payload via cleavable linker.\nMethods: the fully human monoclonal antibodies were derived from transgenic mouse model NeoMab mice. Flow cytometry was performed to examine binding of ADCs to tumor cells. In addition, we used pHrodo conjugated to ADCs to detect internalization activity in tumor cells. CTG (CellTiter-Glo®) assay was employed to measure cell viability. In immunodeficient mice, xenograft model was generated to assess the tumor growth inhibition of ADCs.\nResults: EGFR/B7H3-ADCs showed stronger binding to tumor cells than EGFR-ADC and B7H3-ADC. Besides, EGFR/B7H3-ADCs displayed superior internalization activity. More importantly, our EGFR/B7H3-ADCs suppressed tumor growth more effectively than EGFR-ADC and B7H3-ADC in CDX mouse model.\nConclusion: our EGFR/B7H3-ADCs show potential therapeutic promise in patients with EGFR or B7H3 positive tumors. This study provides crucial rationale for supporting the further development of our novel dual-targeted Antibody-drug Conjugates (ADCs).", "source_company": "NeoMab Biotechnology Co,. Ltd", "source_org_type": "公司", "row_number": 1241, "target_meta": "EGFR,CD276", "MOA_meta": "抗体偶联药物"}, {"drug_name": "LCMV-WE", "company": "Heinrich-Heine-Universität Düsseldorf", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "中", "total_score": 55.5, "institution_score": 35, "track_score": 75, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 4, "brief_reason": "基于LCMV的工程化非溶瘤型病毒通过肿瘤特异性T细胞扩增和募集产生抗肿瘤免疫效应，靶点未明确披露。大学机构分数较低，但病毒免疫放大机制新颖且与BiTE/CAR-T协同潜力强，preclinical数据较扎实。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5578", "id": "01XM_5wBX1NQZOEH-LO6", "source_drug_name": "LCMV-WE", "title": "Arenavirus based Non-lytic Viral Immune Drivers with tumor-tropic mutations as new class of amplificators of anti-tumoral T cell responses", "abstract_text": "Background: Recent understandings of anti-tumoral immune mechanisms reveal that the strong and sustainable activation of specific CD8+ T cells in the tumor is one major trigger for successful immunotherapy. Checkpoint blockade, therapeutic vaccine, bi-specific T cell engager (BiTE) and CAR-T cells have strongly contributed to such tumor-specific T cell activation, however especially for solid cancers complete remission is limited. Recently, we showed that the non-cytopathic lymphocytic choriomeningitis virus (LCMV) induces strong anti-tumor responses without directly killing tumor cells. LCMV triggers infiltration of CD8+ T cells into the tumor leading to a sustained T cell dependent tumor regression. Here, we aim to generate an optimized arenavirus based on LCMV for the application of this new anti-tumoral mechanism in cancer patients.\nMethods: We aimed to adapt LCMV strain WE to tumor tissues. We performed multiple passaging of the wild-type strain LCMV-WE in several murine and human cancer cells. The occurring mutations were identified, their role in tumor cell tropism confirmed in vitro and in vivo, and the most effective ones were combined in an attenuated reassortant LCMV.\nResults: We identified several mutations, which showed accelerated propagation in cancer cells. By combining the identified mutations in attenuated reassortant LCM viruses, we generated arenavirus strains with accelerated entry and replication in a broad spectrum of human cancer cells. One of these strains exhibited strong anti-tumoral efficacy in a variety of tumor models with minimal replication in healthy tissues and no severe disease symptoms in immune compromised murine model systems. Dissecting the anti-tumoral mechanism revealed that tumor-specific T cells were expanded, T cells recruited to tumors and differentiated into potent effector cells. Due to this specific mode of action, this virus strain amplified the anti-tumoral activity of a BiTE (Trp1/CD3) and CAR-T cells to result in a strong synergistically acting tumor therapy. In non-human primates, treatment with this strain led to substantially increased virus-mediated cytokine and chemokine levels as well as T cells in the blood by maintaining a safe application.\nConclusions: In conclusion, by using the biological principle of mutation and selection, we developed an arenavirus-based immune therapy safely applied in preclinical model systems and GLP studies as well as harbouring a unique mode of action and proprietary anti-tumoral efficacy. Combination with T cell-directed therapies including BITEs results in strong synergistic anti-tumoral responses.", "source_company": "Heinrich-Heine-Universität Düsseldorf", "source_org_type": "大学", "row_number": 1258, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "CC10230", "company": "Aglaeapharma INC.", "org_type": "公司", "target": "α2A-adrenoceptor", "modality": "agonist", "importance_level": "中", "total_score": 55.3, "institution_score": 45, "track_score": 55, "milestone_score": 65, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "CC10230为新型外周限制性α2A-adrenoceptor激动剂，通过抑制肿瘤生长并缓解癌痛实现双重抗肿瘤支持治疗。机构为小型美国biotech（非头部），赛道为靶向交感神经调控的肿瘤微环境新策略（非主流热门），但展示preclinical体内显著疗效及良好安全性，整体中等潜力。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6417", "id": "aZ7M_5wBZznHJdnt_W3O", "source_drug_name": "CC10230", "title": "Targeting peripheral α2A-adrenoceptors as a dual-benefit approach for integrated cancer therapy and supportive care", "abstract_text": "Background: Emerging evidence highlights sympathetic innervation is a key component of the tumor microenvironment, and that denervation effectively suppresses tumor growth, revealing new therapeutic opportunities (Vera Thiel, Nature 2025). α2A-adrenoceptor (α2AAR) agonists like clonidine are potent regulators of sympathetic activity, and have demonstrated antitumor efficacy (Jingjing Zhu, Nature 2023), yet their application in oncology can be severely limited by the central nervous system (CNS)-mediated adverse effects, including sedation and hypothermia. To overcome this challenge, we developed CC10230, a novel peripherally restricted α2AAR agonist designed to provide sustained antitumor therapy without dose-limiting CNS toxicity.\nMethod: A focused compound library was generated through rational design and screened based on in vitro α2AAR potency, P-gp efflux ratio, and oral bioavailability. Peripheral restriction of the lead compound was confirmed using in vivo distribution pharmacokinetic. Anti-tumor activity was assessed in the MC38 subcutaneous tumor model in mice, and anti-allodynic efficacy was evaluated in the NCTC-2572 cell-induced bone cancer pain model in mice. All clinical observations, including behavior and safety monitoring, were conducted in accordance with CRO's standard operating procedure (SOP).\nResult: CC10230 was selected as a lead compound based on its high α2AAR activity (EC50= 7.5 nM, Ki = 58.1 nM), strong P-gp substrate properties (efflux ratio = 51.0), and a favorable oral bioavailability (44.6%). Pharmacokinetic studies confirmed minimal CNS penetration (Kp,uu,brain < 0.03), markedly lower than that of clonidine, supporting strong peripheral restriction. In the MC38 model, CC10230 (5 mg/kg, b.i.d., p.o.) significantly suppressed tumor growth, achieving a TGI of 62.3% at Day 17. Clonidine (5 mg/kg, b.i.d., p.o.) as a positive control also achieved significant TGI but was poorly tolerated, causing pronounced somnolence, hypothermia, and 18.1% body weight loss. In contrast, CC10230 showed no tolerability issues. Additionally, CC10230 exhibited robust efficacy in cancer pain model, confirming its dual therapeutic benefits.\nConclusion: These findings establish peripheral α2AAR activation as a promising two-pronged translational strategy for integrated oncology care, simultaneously inhibiting tumor progression and alleviating cancer-related pain while circumventing CNS-mediated side effects. The favorable safety profile of CC10230 supports its potential for sustained antitumor therapy without the tolerability limitations of conventional α2AAR agonists.", "source_company": "Aglaeapharma INC.", "source_org_type": "公司", "row_number": 1253, "target_meta": "ADRA2A", "MOA_meta": "激动剂"}, {"drug_name": "ML-B01", "company": "Stanford University", "org_type": "大学", "target": "Akt", "modality": "inhibitor", "importance_level": "中", "total_score": 55, "institution_score": 35, "track_score": 75, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "ML-B01为ipatasertib的脑渗透新型类似物，靶向Akt抑制剂，具有良好BBB渗透性和脑内外持久PD效应。斯坦福大学学术机构基础分较低，但Akt抑制剂赛道仍具热度，工具平台创新及类PROTAC持久效应提供一定加分，总分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6243", "id": "F1XM_5wBX1NQZOEH-LS6", "source_drug_name": "ML-B01", "title": "Pharmacodynamics of Akt drugs revealed by a kinase-modulatedbioluminescent indicator withBBB-permeable substrate", "abstract_text": "Noninvasive imaging tools that enable real-time visualization of biological events in living subjects are highly valuable in biomedical research. Bioluminescence imaging (BLI), with its high sensitivity and low background, provides an ideal platform for developing molecular sensors to monitor intracellular signaling in vivo. Here, we report the development of a kinase-modulated bioluminescent indicator (KiMBI) for rapid, noninvasive pharmacodynamic (PD) assessment of Akt-targeted therapeutics, substantially reducing compound use and animal requirements. This ATP-independent reporter, based on NanoLuc luciferase, produces light upon administration of the brain-penetrant substrate cephalofurimazine (CFz9). Using KiMBI, we performed a structure-PD relationship analysis of the brain-active Akt inhibitor ipatasertib by designing and characterizing two novel analogs. One analog, ML-B01, exhibited robust Akt inhibition in both brain and peripheral tissues. Remarkably, capivasertib, ipatasertib, and ML-B01 all demonstrated prolonged PD effects that outlasted their pharmacokinetic (PK) profiles. Furthermore, KiMBI imaging revealed that the PD effect of an Akt-targeted proteolysis-targeting chimera (PROTAC) degrader persisted for more than three days following a single dose. Together, these results establish bioluminescence imaging with the Akt KiMBI as a sensitive and efficient method for real-time, longitudinal visualization of Akt inhibitor and degrader activity in vivo. This platform offers a powerful approach for early-stage drug optimization and for elucidating the pharmacodynamics of kinase-targeted therapies in live animals.", "source_company": "Stanford University", "source_org_type": "大学", "row_number": 251, "target_meta": "Akt", "MOA_meta": "抑制剂"}, {"drug_name": "IHK-44", "company": "Case Western Reserve University School of Medicine", "org_type": "大学", "target": "CBP/p300", "modality": "inhibitor", "importance_level": "中", "total_score": 55, "institution_score": 35, "track_score": 75, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "IHK-44为新型CBP/p300双重抑制剂，针对融合阳性横纹肌肉瘤（FP-RMS）显示选择性抑制P3F驱动转录活性，并在900个细胞系筛选中对FP-RMS高度敏感。机构为大学非商业研发导致分数较低，但表观遗传靶点在儿科肿瘤中有潜力且机制新颖，preclinical数据较扎实。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8680", "id": "K1XM_5wBX1NQZOEH-LK6", "source_drug_name": "IHK-44", "title": "Mechanistic understanding of a novel CBP/p300 inhibitor in fusion-positive rhabdomyosarcoma", "abstract_text": "Fusion-positive rhabdomyosarcoma (FP-RMS) is a pediatric soft tissue carcinoma characterized by poor survival rate and limited therapeutic options. The fusion oncoprotein PAX3-FOXO1 (P3F) is the key driver for FP-RMS, and its transcriptional activity is dependent on histone acetyltransferase CBP/p300. Given the challenge of directly targeting the transcription factor P3F, CBP/p300 represents an attractive therapeutic target in treating FP-RMS. Through a focused screening of different epigenetic-modifying agents against FP-RMS, the inhibition of CBP/p300 emerged as the most effective strategy in selectively suppressing P3F-driven transcriptional activity. To overcome the limitations, such as toxicity and efficacy of the existing CBP/p300 inhibitors, we employed structure-based drug design to develop a potent CBP/p300 dual inhibitor, IHK-44. We used chemical genetic approaches to enable precise and temporal control of its function in investigating the underlying mechanism of CBP/p300 in the context of FP-RMS. In studying the basis of IHK-44’s selectivity and potency in FP-RMS compared to other CBP/p300 inhibitors and degraders, we conducted a comprehensive series of studies, including luciferase reporter assays, live-cell imaging, RNA-seq, ChIP-seq, and proteomics. These studies revealed that FP-RMS exhibits unique epigenetic dependencies, particularly at 3D clusters of histone acetylation lacking CpG islands. The predictor of gene responsiveness to CBP/p300 inhibition with IHK-44 is to be found by mapping the 3D enhancer/promoter loops into clusters and quantifying the extent of CpG island involvement in the elements that make up clusters. Genes driven CpG-poor clusters, often very rich in enhancers, are hypersensitive to IHK-44, while CpG-rich clusters, usually promoter-rich, are recalcitrant. This allows us to define clear categorization to distinct types of gene regulation hubs in the cancer epigenome. High-throughput screening across 900 cell lines revealed that FP-RMS is one of the cancer subtypes most sensitive to IHK-44, whereas normal cell lines and fusion-negative RMS were resistant. In summary, our findings suggest a novel therapeutic strategy for FP-RMS by targeting CBP/p300 and highlight the potential of IHK-44 as a promising candidate for further preclinical development.", "source_company": "Case Western Reserve University School of Medicine", "source_org_type": "大学", "row_number": 515, "target_meta": "CBP/EP300", "MOA_meta": "抑制剂"}, {"drug_name": "GRB2 inhibitors", "company": "UT MD Anderson Cancer Center", "org_type": "医院", "target": "GRB2", "modality": "inhibitor", "importance_level": "中", "total_score": 55, "institution_score": 35, "track_score": 75, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 5, "brief_reason": "靶点为GRB2，通过稳定非活性二聚体实现小分子抑制，主要影响DDR通路并激活cGAS/STING免疫，机制新颖且克服了长期undruggable难题。机构为顶级癌症医院而非商业公司导致institution_score较低，但热门靶点机制+preclinical强度+免疫潜力使整体赛道与领域热度较高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4573", "id": "vlXM_5wBX1NQZOEH-LK6", "source_drug_name": "GRB2 inhibitors", "title": "Chemical trapping of inactive GRB2 dimer unveils a novel cancer vulnerability by coupling replication stress to anti-tumor immunity", "abstract_text": "Growth Factor Receptor-Bound protein 2 (GRB2), a critical signal transduction adaptor, has been an elusive therapeutic target due to its ubiquitous SH2/SH3 domains, despite prior clinical evidence (e.g. a striking 75% complete remission in AML patients using liposomal antisense GRB2 RNA) supporting the high value of its inhibition. We overcame this long-standing \"undruggable\" challenge by leveraging our discovery that the GRB2 dimer is its auto-inhibited form with a unique druggable interface. We will report the structure-guided discovery and optimization of small molecule GRB2 inhibitors (GRB2i) that act by stabilizing this inactive dimer. Combining experimental structural biochemistry and AI-Machine Learning (AI-ML) refinement across chemical space, we have developed potent clinical leads. Our data reveal GRB2i primarily targets cancer-critical DNA Damage Response (DDR) pathways, rather than canonical GRB2 roles in cell growth and proliferation. Specifically, our GRB2i chemically induces catastrophic Homologous Recombination (HDR) deficiency and replication fork instability. This vulnerability renders cancer cells exquisitely sensitive to PARP inhibitors and other DNA damaging agents. Importantly, we show that GRB2i activates the cGAS/STING pathway, triggering the release of pro-inflammatory cytokines and creating a significant immune destruction liability for cancer cells. These collective results unveil a novel structure-guided strategy for small molecule GRB2 inhibition, demonstrating its potential as a single agent or strategic combination therapy to enhance anti-tumor immunity and exploit a central cancer vulnerability.", "source_company": "UT MD Anderson Cancer Center", "source_org_type": "医院", "row_number": 609, "target_meta": "GRB2", "MOA_meta": "抑制剂"}, {"drug_name": "methylseleninic acid", "company": "Mayo Clinic Arizona", "org_type": "医院", "target": "未披露", "modality": "other", "importance_level": "中", "total_score": 55, "institution_score": 35, "track_score": 75, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "methylseleninic acid (MSA) 作为TGF-β1抑制剂增强anti-FN14 CAR-T细胞功能，针对TGF-β富集实体瘤有协同潜力。机构为医院系统得分较低，但CAR-T协同+实体瘤TGF-β难题+preclinical数据清晰使其整体中等偏上重要性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4022", "id": "1VXM_5wBX1NQZOEH-LO6", "source_drug_name": "methylseleninic acid", "title": "Methylseleninic acid enhances anti-FN14 CAR-T cell effector function and redirects cytotoxicity against TGF-β-rich kidney, prostate, and brain tumors", "abstract_text": "Background: Clear cell renal cell carcinoma (ccRCC), metastatic castration-resistant prostate cancer (mCRPC), and glioblastoma (GBM) are treatment-refractory tumors marked by high TGF-β1, a master suppressor of antitumor immunity and antigen presentation. Pharmacologic methylseleninic acid (MSA) potently inhibits TGF-β1, PD-L1, and VEGF without significant off-target toxicity. FN14, the TWEAK receptor and a metastasis driver, is selectively overexpressed in these malignancies, making it a high-specificity CAR-T target.\nMethods: We developed second-generation anti-FN14 CARs with CD28 or 4-1BB costimulation and CD3ζ signaling and lentivirally transduced them into human CD4⁺/CD8⁺ T cells. Cytotoxicity against FN14⁺ ccRCC, mCRPC, GBM lines and patient-derived tumors was measured using LDH release and xCELLigence assays. Effector function was assessed by intracellular cytokines, phenotyping, and multiplex analysis. MSA was tested at physiologic concentrations to evaluate effects on CAR-T viability, metabolism, function, and tumor susceptibility.\nResults: Anti-FN14 CAR-T cells mediated rapid, antigen-specific lysis across all tumor types, achieving >50% specific lysis at an E:T ratio of 1:1. MSA (2.5-5 µM) reduced tumor PD-L1 and TGF-β by >40% and improved CAR-T metabolic activity, enhancing IL-2 and IFN-γ secretion. Manufacturing CAR-T cells with MSA (2.5 µM) increased cytotoxicity and persistence versus controls (p < 0.01). MSA’s effects were dose- and schedule-dependent at clinically compatible concentrations without detectable off-target toxicity.\nConclusion: MSA augments anti-FN14 CAR-T cytotoxicity, metabolic fitness, and sustained effector function by suppressing tumor-derived TGF-β1 and PD-L1 and directly enhancing CAR-T activity. As a clinically relevant TGF-β1 inhibitor and active seleno-L-methionine metabolite, MSA represents a readily translatable strategy to reduce CAR-T exhaustion and improve efficacy in TGF-β-rich solid tumors.", "source_company": "Mayo Clinic Arizona", "source_org_type": "医院", "row_number": 800, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "proprietary compounds", "company": "Kongs Pharmaceutical", "org_type": "公司", "target": "未披露", "modality": "other", "importance_level": "中", "total_score": 55, "institution_score": 45, "track_score": 75, "milestone_score": 50, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "药品为内部专有化合物，靶点和具体机制未明确披露，仅通过AI平台筛选显示潜在抑制macropinocytosis依赖癌症的共享信号轴。机构为小型/未知公司，得分一般；赛道涉及AI药物发现+肿瘤营养摄取新策略具一定热度，但处于早期筛选阶段，里程碑价值有限。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6486", "id": "A1XM_5wBX1NQZOEH-LS6", "source_drug_name": "proprietary compounds", "title": "A translational screening platform with AI integration for clinically predictive discovery of safe and effective macropinocytosis-dependent cancer therapeutics", "abstract_text": "Background: Macropinocytosis-dependent cancers rely on nutrient-scavenging pathways to sustain tumor growth under stress. Current therapies rarely provide durable control, underscoring the need for strategies that stabilize cancer progression as a chronic condition. Although extensive clinical data exist for approved drugs—linking mechanisms of action (MoAs), safety, and efficacy—clinically translatable, macropinocytosis-relevant cell-based screens remain limited. We developed an AI-driven translational discovery platform integrating phenotypic screening with clinical correlation to identify safe, mechanistically meaningful, and clinically predictive therapeutic candidates.\nMethods: An automated image-based cytometry assay was optimized to quantify macropinocytosis in cancer cells with minimal human bias. FDA-approved drugs and proprietary compounds were screened with this medium throughput method. AI algorithms correlated in vitro phenotypes with retrospective clinical data, integrating MoA, toxicity, and efficacy metrics. Mechanistic clustering identified shared therapeutic pathways among clinically effective agents. AI modeling also predicted clinical performance and generated rational combination hypotheses emphasizing safety and translational potential.\nResults: AI validation confirmed strong concordance between phenotypic results and clinical safety/efficacy profiles from 892 FDA-approved cancer and non-cancer drugs, demonstrating high translational fidelity. Mechanistic clustering revealed a convergent signaling axis associated with durable benefit and low toxicity. Several novel in-house compounds exhibited comparable inhibition profiles and AI-predicted clinical potential. AI modeling proposed synergistic combinations between approved and proprietary agents with underexplored mechanisms, prioritizing safe, durable therapeutic responses.\nConclusions: This platform unites bias-free phenotypic assays with AI-guided clinical validation, enabling early identification of therapeutically meaningful and translatable drug candidates. Discovery of a shared mechanistic target and AI-predicted novel compounds demonstrates a clinically grounded, data-driven model for developing safe, effective, and chronic disease-oriented cancer therapies.\nKeywords: Phenotypic screening; macropinocytosis; AI drug discovery; translational oncology; clinical validation; mechanistic clustering; combination therapy; drug repurposing; safety profiling", "source_company": "Kongs Pharmaceutical", "source_org_type": "公司", "row_number": 831, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "allosteric covalent GSTO1 inhibitors", "company": "ChomiX Biotech. Co. Ltd.", "org_type": "公司", "target": "GSTO1", "modality": "inhibitor", "importance_level": "中", "total_score": 55, "institution_score": 45, "track_score": 65, "milestone_score": 60, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "靶向GSTO1的别构共价抑制剂，通过抑制NLRP3炎症小体激活展现抗炎潜力；ChomiX作为国内新兴chemoproteomics平台biotech公司，化合物处于lead优化阶段并有新结合模式亮点，但整体仍为preclinical早期项目。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11304", "id": "dFXM_5wBX1NQZOEH-LS6", "source_drug_name": "allosteric covalent GSTO1 inhibitors", "title": "Chemoproteomic discovery of allosteric covalent GSTO1 inhibitors reveals a previously unrecognized binding mode with anti-inflammatory activity", "abstract_text": "Abstract is embargoed at this time.", "source_company": "ChomiX Biotech. Co. Ltd.", "source_org_type": "公司", "row_number": 913, "target_meta": "GSTO1", "MOA_meta": "抑制剂"}, {"drug_name": "CAR-T cell therapy", "company": "Immudex", "org_type": "公司", "target": "未披露", "modality": "CAR", "importance_level": "中", "total_score": 55, "institution_score": 45, "track_score": 85, "milestone_score": 40, "field_heat_score": 80, "bonus_score": 0, "brief_reason": "产品为CAR-T细胞监测用多聚体试剂（CAR-Dextramer®），靶点未披露，属于CAR-T领域工具/检测平台。机构为小众试剂公司赛道热度高但开发阶段偏工具而非治疗性产品导致里程碑分较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4562", "id": "uJ3ECZ0B4z9FlvORyiZD", "source_drug_name": "CAR-T cell therapy", "title": "CAR-T-cell monitoring using specific multimers: a fast and specific method allowing uniform evaluation", "abstract_text": "CAR-T cell immunotherapy is used successfully against refractory hematological and solid cancer. Cellular Monitoring of CAR-T cells is important both for validating expression of the CAR construct in the transduced T cells prior to infusion, and persistence of the CAR-T cells in the blood of the recipient. CAR expression is often detected by fluorochrome conjugated antibody against a structural part of the CAR construct, and not the specific target for the CAR interaction. We have developed a flexible platform to manufacture direct CAR-T cells detecting multimer reagents, CAR-Dextramer® allowing detection of CAR-T cells of different specificities and affinities Activation of chimeric antigen receptor T (CAR-T) cells are critical for ensuring therapeutic efficacy in adoptive immunotherapy. CAR-T cell activation requires two signals: antigen recognition through the CAR and co-stimulation via intracellular interactions, and by stimulatory molecules such as interleukins. Control of activation and continuous monitoring are essential to optimize potency to improve clinical outcomes in hematologic and solid tumors immunotherapy.\nWe have developed CAR-T cell activation reagents based on the CAR-Dextramer® scaffold, that contain said stimulatory molecules. These reagents can be used to evaluate the ability of the transduced CAR-T cells to be stimulated or expanded through the specific interaction with its cognate target, and costimulatory signals.", "source_company": "Immudex", "source_org_type": "公司", "row_number": 1177, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "9E3-PBD", "company": "UTHealth Houston", "org_type": "大学", "target": "GPR56", "modality": "ADC", "importance_level": "中", "total_score": 54.8, "institution_score": 35, "track_score": 85, "milestone_score": 45, "field_heat_score": 75, "bonus_score": 3, "brief_reason": "靶点GPR56为 adhesion GPCR，通过非激动性抗体9E3构建的ADC（PBD payload）针对TNBC显示良好选择性潜力。机构为大学得分较低，但ADC+新型靶点在TNBC领域有较高赛道热度，目前处于体外/体内评价的preclinical早期阶段。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5730", "id": "JlXM_5wBX1NQZOEH-LG5", "source_drug_name": "9E3-PBD", "title": "Therapeutic targeting of adhesion receptor GPR56 for the treatment of triple-negative breast cancer", "abstract_text": "Triple-negative breast cancer (TNBC) is an aggressive subtype lacking durable targeted therapies, and resistance continues to drive poor clinical outcomes. The clinical success of antibody-drug conjugates (ADCs), which combine antibody specificity with potent cytotoxic payloads, highlights their growing clinical impact. Although the approved anti-TROP2 ADC, sacituzumab govitecan, provides clinical benefit, it causes toxicity in normal tissues, underscoring the need for more selective therapeutic strategies. Adhesion-mediated signaling through the FAK-SRC axis is a major survival pathway under therapeutic stress. Our previous study showed that GPR56, an adhesion G protein-coupled receptor (GPCR), activates the FAK-SRC pathway and that targeting GPR56 with an ADC elicited potent antitumor efficacy in colorectal cancer models. Given these results, we examined GPR56 as a potential therapeutic target in TNBC. While TROP2 is a validated ADC target in TNBC, its expression in normal tissues limits tumor selectivity. GPR56, by contrast, is highly expressed in TNBC and associated with poor prognosis, yet shows limited normal tissue expression, potentially conferring a superior therapeutic index for GPR56-targeted ADCs. Our first-generation anti-GPR56 ADC (10C7-Duo), incorporating the DNA-damaging payload duocarmycin, exhibited target-dependent cytotoxicity in GPR56-positive TNBC cell lines, confirming that GPR56 is a viable therapeutic target. However, the monoclonal antibody (mAb) 10C7 exhibited agonistic activity, which could limit its therapeutic potential. Thus, we developed 9E3, a non-agonist anti-GPR56 mAb that internalizes efficiently and traffics to lysosomes for payload delivery. 9E3 was conjugated to a more potent pyrrolobenzodiazepine (PBD) payload using site-specific chemistry, and analyses confirmed successful conjugation, stability, and preserved antigen binding. Functional studies in breast cancer models showed that GPR56 knockdown suppressed, while overexpression enhanced, FAK-SRC phosphorylation, tumor cell growth, and invasion. Currently, we are evaluating 9E3-PBD for in vitro cytotoxic potency and selectivity, as well as in vivo safety and antitumor efficacy in TNBC cell line xenografts and patient-derived models. These findings help establish GPR56 as a clinically relevant adhesion GPCR and introduce a novel ADC approach to target therapeutic resistance in TNBC. By integrating receptor biology with targeted payload delivery, this work lays the foundation for potentially safer and more selective therapeutic options for TNBC patients.", "source_company": "UTHealth Houston", "source_org_type": "大学", "row_number": 336, "target_meta": "ADGRG1", "MOA_meta": "抗体偶联药物"}, {"drug_name": "chimeric antigen receptor T cell therapy", "company": "Navigate BioPharma Services, Inc.", "org_type": "公司", "target": "未披露", "modality": "CAR", "importance_level": "中", "total_score": 54.5, "institution_score": 45, "track_score": 90, "milestone_score": 30, "field_heat_score": 85, "bonus_score": 0, "brief_reason": "该条为新一代CAR-T细胞疗法的监测方法研究（多重dPCR），非药物本身研发，靶点未披露。CAR赛道热度极高，但机构为服务型CRO类公司、非核心创新机构，开发阶段为工具优化而非里程碑性药物进展。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9760", "id": "iFXM_5wBX1NQZOEH-LK6", "source_drug_name": "chimeric antigen receptor T cell therapy", "title": "Assessment of spectral overlap and crosstalk in multiplex digital PCR for effective monitoring of next-generation CAR T-cells in cancer clinical trials", "abstract_text": "Introduction: As new chimeric antigen receptor (CAR) T cells emerge as secondary therapies in patients already treated with an approved CAR, clinical trial investigation of next generation constructs requires monitoring for the presence of residual first generation CAR-T therapies, often from limited patient samples. Multiplex digital PCR (dPCR) enabling absolute quantification without standard curves and supporting detection of as few as 10 copies, is an ideal approach to monitor multiple approved CAR-Ts in a limited clinical trial specimen (Morley, 2014; QIAGEN, n.d.). While multiplexing improves efficiency, it introduces challenges such as spectral overlap, potentially causing crosstalk and misinterpretation. Herein, we investigate how bleed-through affects signal interpretation in multiplex dPCR and evaluate the effectiveness of threshold adjustments and software updates in mitigating crosstalk and preserving monitoring accuracy of multiple CAR-Ts on the QIAcuity platform.\nMethod: A multiplexed dPCR assay targeting three CAR domains, a viral safety marker, and one reference gene was tested using probes labeled with FAM, TxRED, VIC, TAMRA, and Cy5 across five optical channels. Two formats were run on QIAcuity: singleplex reactions to confirm specificity and baseline crosstalk, and multiplexed reactions to assess cumulative interference. Analysis was performed using Software Suite (SS) versions 2.5 and 3.1. Fluorescence plots assessed signal clarity, crosstalk, and the impact of optical and threshold settings on droplet classification and quantification. \nResult : Singleplex reactions showed no bleed-through in FAM, VIC, TAMRA, or Cy5 channels. TxRed bled into Cy5. TxRED bled into Cy5, and TAMRA into VIC, confirmed by 2D plots showing double-positive patterns and unexpected VIC-positive droplets in TAMRA-only samples. VIC-to-TAMRA crosstalk was concentration-dependent, decreasing at lower input levels, while TxRED-to-Cy5 remained constant. Signal clarity for TAMRA improved with optical or threshold adjustments. Despite visible bleed-through, multiplex quantification remained accurate. Cy5-labed targets were correctly identified, with software ignoring TxRED bleed-through. No differences in crosstalk or quantification accuracy were observed between SS versions 2.5 and 3.1, confirming consistency across updates.\nConclusion:  Spectral bleed-through, especially from TxRED into Cy5, was a key source of signal misclassification. Manual thresholding and optical adjustments in both software versions effectively reduced crosstalk and improved quantification of all CAR domains. These findings highlight the importance of optimized assay design and analysis tools for reliable quantification of residual CAR-T therapies, which are critical for safe advancement of next generation CAR-T therapies.", "source_company": "Navigate BioPharma Services, Inc.", "source_org_type": "公司", "row_number": 41, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "isobutyl-deoxynyboquinone", "company": "National Cancer Institute", "org_type": "研究机构/政府机构", "target": "NQO1", "modality": "other", "importance_level": "中", "total_score": 54.5, "institution_score": 45, "track_score": 65, "milestone_score": 55, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "IB-DNQ为NQO1激活的醌类化合物，通过无效氧化还原循环产生超氧阴离子靶向FH缺陷肿瘤的需氧糖酵解。机构为政府研究机构非商业公司导致分数一般，赛道为NQO1生物激活策略有一定创新但非热门modality，处于preclinical体内验证阶段显示一定疗效。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9151", "id": "QZ7M_5wBZznHJdnt_W3O", "source_drug_name": "isobutyl-deoxynyboquinone", "title": "EPR imaging of oxygen consumption driven by NQO1-activated compounds in FH-deficient renal tumors", "abstract_text": "Patients with hereditary leiomyomatosis and renal cell carcinoma (HLRCC), characterized by mutations in the fumarate hydratase (FH) gene, are at risk for development of aggressive FH-deficient RCCs. FH-deficient tumor cells undergo a pronounced and irreversible metabolic shift to lactate fermentation due in part to loss and mutation of mitochondrial DNA. Fumarate accumulation in FH-deficient tumor cells leads to increased expression of NAD(P)H-quinone oxidoreductase 1 (NQO1) through activation of the NRF2 transcription factor. Although several therapeutic agents have shown promise in the treatment of FH-deficient RCC, clinical outcomes in patients remain unsatisfactory. In this study, we examined the mechanism and therapeutic efficacy of isobutyl-deoxynyboquinone (IB-DNQ), which undergoes futile redox cycling in the presence of NQO1 and oxygen, leading to sustained generation of the highly reactive and toxic superoxide anion. First, we found that patient-derived FH-deficient tumor cells exhibit minimal oxygen consumption in vitro, and EPR oxygen mapping of FH-deficient tumor xenografts in vivo revealed that tumor oxygen levels were elevated relative to other genetically defined in vivo models of RCC. Infusion of IB-DNQ in tumor-bearing animals resulted in rapid and robust non-mitochondrial oxygen consumption in FH-deficient tumor xenografts as measured by both EPR oxygen imaging and photoacoustic mapping of tumor hemoglobin saturation. Repeated doses of IB-DNQ resulted in reduced tumor growth rates. Metabolomic analyses revealed that IB-DNQ treatment strongly suppressed glycolysis and reduced cellular ATP levels by rapidly depleting NADH and NADPH in FH-deficient tumor cells. Finally, [1-13C]pyruvate hyperpolarized MR spectroscopy revealed decreased conversion of pyruvate to lactate in FH-deficient tumor xenografts following IB-DNQ treatment, providing a direct measurement of the impact of IB-DNQ on lactate fermentation in vivo. The combination of these in vivo imaging techniques and metabolite measurements demonstrate that NQO1-activated quinones can effectively target aerobic glycolysis in FH-deficient tumors which rely heavily on lactate fermentation for growth.", "source_company": "National Cancer Institute", "source_org_type": "研究机构\n政府机构", "row_number": 265, "target_meta": "NQO1", "MOA_meta": "其他"}, {"drug_name": "anti-PD-(L)1", "company": "Johns Hopkins University", "org_type": "大学", "target": "PD-1/PD-L1", "modality": "inhibitor", "importance_level": "中", "total_score": 54.5, "institution_score": 35, "track_score": 85, "milestone_score": 50, "field_heat_score": 80, "bonus_score": 0, "brief_reason": "anti-PD-(L)1为经典PD-1/PD-L1抑制剂，靶点及免疫治疗赛道成熟且临床应用广泛。大学机构非核心药企、摘要聚焦ctDNA监测而非药物新机制或里程碑进展，导致综合重要性中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3216", "id": "Mp7ECZ0BZznHJdntvNYd", "source_drug_name": "anti-PD-(L)1", "title": "Clinical utility of landmark ctDNA molecular response as an early indicator of immunotherapy outcomes in lung cancer", "abstract_text": "Background: Circulating tumor DNA (ctDNA) analyses are informative as an early indicator of immunotherapy response in advanced non-small cell lung cancer (NSCLC), however the clinical role of ctDNA molecular response requires further validation.\nMethods: As part of a prospective clinical protocol (NCT05995821), we performed ctDNA (n=328) and matched white blood cell DNA (WBC; n=109) targeted 521 fixed gene panel next-generation sequencing (Elio Plasma Complete) from 109 patients with advanced/metastatic NSCLC who received anti-PD-(L)1 as monotherapy or in combination with chemotherapy. Following variant cellular origin resolution, landmark molecular response (mR) was defined as undetectable ctDNA within 3-9 weeks of treatment initiation. For a subset of patients (n=34), whole-exome sequencing of baseline tumors was performed and used in benchmarking ctDNA detection and therapy response assessment.\nResults: Among 2,818 plasma variants, 23% were clonal haematopoiesis-related, which confounded the interpretation of driver gene associations with clinical outcomes and assessment of molecular responses. Implementing a tumor-naïve WBC DNA-informed approach increased the number of evaluable cases while maintaining the overall accuracy of landmark ctDNA molecular responses. Pre-treatment ctDNA burden but not blood tumor mutation burden, predicted survival. Overall, 77 patients were evaluable for landmark molecular response assessment; of these, 29 patients (38%) attained a mR. Landmark evaluation of molecular response enabled evaluation of all cases, was highly specific (92%), and achieved a higher sensitivity (66%) compared to clearance or ctDNA reduction from baseline (sensitivity 59%). In predicting landmark progression-free survival (PFS) at 6 months (durable clinical benefit, DCB), the tumor-agnostic WBC-informed approach strikes a balance between sensitivity (71.4%) and specificity (100%) compared to plasma-only (sensitivity=14.3%, specificity=100%) or tumor-informed (sensitivity=78.6%, specificity=71.4%) approaches. A significant enrichment in landmark ctDNA mR was noted among patients with DCB with immunotherapy (p=2.5e-05) and chemo-immunotherapy (p=0.02). Patients in the landmark mR group attained longer PFS (p=1.6e-06) and overall survival (p=2.5e-05) compared to those with molecular progression. The association between landmark molecular response and survival remained significant (PFS and OS, P < 0.001) after accounting for clinical covariates, line of therapy, and baseline ctDNA levels.\nConclusions: Our findings indicate that landmark ctDNA molecular response at 3-9 weeks on treatment provides a real-time and accurate approach for monitoring immunotherapy clinical outcomes. Although not currently validated for regulatory use, these findings demonstrate the potential utility of ctDNA as an early endpoint in clinical trials.", "source_company": "Johns Hopkins University", "source_org_type": "大学", "row_number": 350, "target_meta": "PD1/PDL", "MOA_meta": "抑制剂"}, {"drug_name": "TPPB", "company": "ETH Zurich", "org_type": "大学", "target": "PKC", "modality": "inhibitor", "importance_level": "中", "total_score": 54.5, "institution_score": 35, "track_score": 75, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "TPPB为PKC激活剂，通过抑制胶质母细胞瘤中肿瘤微管（TM）形成及网络通讯，显示抗肿瘤及放疗协同潜力。机构为大学非商业实体得分较低，但胶母热门靶向新机制+体外体内筛选及多组学验证有一定开发价值。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1899", "id": "-lXM_5wBX1NQZOEH-LG6", "source_drug_name": "TPPB", "title": "Screening for tumor microtube-targeting drugs identifies PKC modulators as multipotent inhibitors of glioblastoma progression", "abstract_text": "Glioblastomas are incurable primary brain tumors that depend on neural-like cellular processes, tumor microtubes (TM), to invade the brain. TMs also interconnect single tumor cells to a communicating multicellular network that resists current therapies. In this study, we developed a combined, comprehensive in vitro/in vivo anti-TM drug screening approach, including machine learning-based analysis tools. Two protein kinase C (PKC) modulators robustly inhibited TM formation and pacemaker tumor cell-driven, TM-mediated glioblastoma cell network communication. As TM-unconnected tumor cells exhibited increased sensitivity to cytotoxic therapy, the PKC activator TPPB was combined with radiotherapy, and long-term intravital two-photon microscopy paired with spatially resolved multiomics revealed anti-TM and antitumor effects. TPPB treatment also decreased the expression of tweety family member 1 (TTYH1), a key driver of invasive TMs. Our study establishes a novel screening pipeline for anti-TM drug development, identifies a TM master regulator pathway, and supports the approach of TM targeting for efficient brain tumor therapies.", "source_company": "ETH Zurich", "source_org_type": "大学", "row_number": 482, "target_meta": "PKC", "MOA_meta": "抑制剂"}, {"drug_name": "anti-PD1", "company": "IUPUI", "org_type": "大学", "target": "未披露", "modality": "inhibitor", "importance_level": "中", "total_score": 54.5, "institution_score": 30, "track_score": 80, "milestone_score": 70, "field_heat_score": 75, "bonus_score": 3, "brief_reason": "研究揭示Folr1作为KRASG12D CRC中介导anti-PD1抵抗的关键基因，抑制Folr1可重编程代谢并恢复对anti-PD1敏感性；虽机构为大学得分较低，但赛道涉及热门免疫治疗抵抗机制与代谢重编程，preclinical体内模型显示显著协同疗效具有转化潜力。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5703", "id": "x1XM_5wBX1NQZOEH-LO6", "source_drug_name": "anti-PD1", "title": "In vivo CRISPR screening uncovers Folr1-mediated metabolic remodeling that sensitizes colorectal cancer to PD-1 blockade", "abstract_text": "Introduction: Colorectal cancer (CRC) is a leading cause of cancer-related mortality worldwide. KRAS mutations are present in approximately 40-50% of CRCs, with G12D being the most prevalent subtype. Accumulating evidence indicates that KRASG12D CRC responds poorly to immune checkpoint blockade (ICB) therapy, reflecting intrinsic resistance to immunotherapy. To identify key regulators capable of overcoming this resistance, we conducted an in vivo CRISPR/Cas9 genetic screen in a KRASG12D-driven CRC model. Furthermore, we investigated the underlying mechanisms contributing to immune resistance.\nMethods: KRASG12D colorectal cancer cell lines, MC38K and Caco2K were generated. An immune-related sgRNA library was designed using PD-1/PD-L1/MHC-I and ESTIMATE data, and MC38K cells carrying the library were tested under anti-PD1 treatment in vivo. RNA sequencing and metabolic profiling were performed to elucidate immune-related mechanisms, and Seahorse assays were used to validate metabolic alterations. Multiple CRC models were used to evaluate Folr1 inhibition combined with anti-PD1 therapy, and a Folr1-based peptide vaccine was developed to overcome resistance.\nResults: KRASG12D overexpression accelerated tumor growth and conferred anti-PD1 resistance in MC38K models. Through the in vivo CRISPR/Cas9 screen, Folr1 emerged as the top depleted gene, ranking first among all candidates associated with immunotherapy resistance. Notably, Folr1 is a clinically actionable target with existing therapeutic antibody currently approved by FDA. RNA-seq analysis of Folr1-knockout MC38K and Caco2K cells revealed profound metabolic remodeling, particularly involving glycolysis. GSEA demonstrated that hallmark pathways including glycolysis, hypoxia, and mTORC1 signaling were downregulated, validated by qRT-PCR, OCR/ECAR assays, and L-lactate measurements. In multiple in vivo models, Folr1 knockout combined with anti-PD1 therapy significantly delayed tumor growth and extended overall survival. Furthermore, the Folr1-based peptide vaccine also markedly suppressed tumor progression.\nConclusions: Our study identifies Folr1 as the top-ranked gene mediating immunotherapy resistance in KRASG12D-driven colorectal cancer. Targeting Folr1 reprograms tumor metabolism, enhances antigen presentation, and restores responsiveness to anti-PD1 therapy. These findings establish Folr1 as a translationally relevant therapeutic target to overcome immune resistance in KrasG12D CRC.", "source_company": "IUPUI", "source_org_type": "大学", "row_number": 789, "target_meta": "not available", "MOA_meta": "抑制剂"}, {"drug_name": "M5A-IR700", "company": "City of Hope Comprehensive Cancer Center", "org_type": "医院", "target": "CEA", "modality": "fluorescent imaging agent", "importance_level": "中", "total_score": 54.5, "institution_score": 45, "track_score": 65, "milestone_score": 60, "field_heat_score": 55, "bonus_score": 0, "brief_reason": "药物为抗CEA人源化抗体M5A偶联IRDye700Dx的光敏剂，用于近红外光免疫治疗（NIR-PIT），靶向CEA阳性结直肠癌诱导免疫原性细胞死亡。机构为知名癌症中心但非头部药企、赛道为新兴NIR-PIT有一定热度但非最热门、仅体外及小鼠体内有效性数据故总分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8538", "id": "3VXM_5wBX1NQZOEH-LO6", "source_drug_name": "M5A-IR700", "title": "Induction of targeted-cytoxicity and immunogenic cell death using an anti-CEA antibody linked to IRDye700Dx", "abstract_text": "Introduction: Near-infrared photoimmunotherapy (NIR-PIT) uses antibody-photosensitizer conjugates to induce spatially controlled and targeted cytotoxicity. The IRDye700DX phthalocyanine photosensitizer undergoes photochemical alterations upon activation with 690 nm light which results in targeted cell death via membrane disruption on cancer cells. This study evaluated the therapeutic efficacy and antigen specificity of a carcinoembryonic (CEA) antigen-targeted NIR-PIT using the humanized anti-CEA antibody (M5A) conjugated to IRDye700Dx (M5A-IR700) in a colon cancer model.\nMethods: M5A was conjugated to NHS-IRDye700DX and validated for binding to human colon cancer cell lines with high-CEA (LS174T), low-CEA (HCT116) by flow cytometry. In vitro, cells were exposed to graded NIR irradiation (690 nm), assessed for cell death (MTS) and evaluated for immunogenic cell death markers (ICD, extracellular ATP, HMGB1). In vivo efficacy was evaluated in athymic mice bearing subcutaneous LS174T xenografts. Mice received intravenous M5A-IR700 (75 μg) followed 24 hours later by a 690 nm laser treatment (150 mW/cm², 30 minutes).\nResults: Flow cytometry confirmed robust, antigen-dependent binding in high-CEA LS174T cells relative to the weak binding observed in low-CEA HCT116 cells (Figure 1A). NIR-PIT with M5A-IR700 resulted in light fluence-dependent and concentration-dependent cytotoxicity (Figure 1B). Maximal phototoxicity was observed in LS174T at 64 J/cm². In contrast, there was minimal response in low CEA expressing HCT116 cells, confirming antigen-density dependent cytotoxicity. Extracellular ATP and HMGB1 were significantly elevated in LS174T but not HCT116 cells (Figure 1C). Rapid release of extracellular ATP occurred immediately following NIR-PIT in LS174T cells and this response was attenuated in HCT116 cells. These findings indicate an antigen-restricted induction of ICD. Mice treated with M5A-IR700 and laser activation (M5A-IR700 PIT)\ndemonstrate significant suppression of tumor volume over 30 days compared with untreated controls and mice receiving antibody alone (p<0.01) (Figure 1E).\nConclusion: CEA-targeted NIR-PIT using M5A-IR700 effectively induced antigen-specific immunogenic cell death in vitro and robust tumor control in vivo. Differential responses between LS174T and HCT116 validate antigen density dependence which is essential for clinical translation. These findings provide strong rationale for clinical development of M5A-IR700-mediated NIR-PIT as targeted therapy for CEA-positive colorectal cancers.", "source_company": "City of Hope Comprehensive Cancer Center", "source_org_type": "医院", "row_number": 806, "target_meta": "CEACAM5", "MOA_meta": "荧光显像剂"}, {"drug_name": "MUC1-TCE", "company": "Nilogen Oncosystems", "org_type": "公司", "target": "MUC1", "modality": "bispecific T-cell engager", "importance_level": "中", "total_score": 54.5, "institution_score": 45, "track_score": 85, "milestone_score": 40, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "MUC1-TCE为Anti-CD3 x Anti-MUC1双特异性T细胞衔接器，靶向在上皮恶性肿瘤中表达的MUC1，展示ex vivo卵巢肿瘤体中诱导T细胞激活和炎症因子释放。Nilogen为小型CRO/biotech公司提供3D肿瘤模型服务，非头部药企导致机构分较低，但双抗TCE赛道及MUC1在实体瘤中的潜力使赛道分较高，总分处于中等水平。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6831", "id": "jVXM_5wBX1NQZOEH-LS6", "source_drug_name": "MUC1-TCE", "title": "Ex vivo evaluation of a MUC1-targeted bispecific T-cell engager in ovarian tumoroids using Nilogen’s 3D-EXpress platform", "abstract_text": "BACKGROUND: Mucin 1 (MUC1) is a relevant target for bispecific T-cell engagers due to its expression in epithelial malignancies. Nilogen Oncosystems’ 3D-EXpress ex vivo tumoroid platform enables direct assessment of patient-specific responses to immunotherapies in a physiologically preserved tumor-immune microenvironment. This study evaluated the activity of a commercially available recombinant Anti-CD3 x Anti-MUC1 bispecific T cell engager antibody (MUC1-TCE) in cryopreserved ovarian tumor-derived tumoroids to characterize immune activation using Nilogen’s integrated platform combining flow cytometry, cytokine profiling, and RNA transcriptomic analysis.\nMETHODS: Pathology reports were reviewed for all tissues and confirmed characteristic histological features consistent with high-grade ovarian carcinoma. Tissues were evaluated for MUC1 expression, showing high to low levels. Tumoroids were generated by mechanical dissociation without enzymatic digestion or in vitro propagation. After thawing, tumoroids were treated with MUC1-TCE, isotype control, or positive control. Multiparametric flow cytometry measured T-cell activation. Parallel supernatants were collected for multiplex cytokine profiling, and RNA was isolated for downstream transcriptional analysis.\nRESULTS: MUC1-TCE treatment induced clear immune activation across multiple tissues. CD4+ T cells upregulated 4-1BB, CD25, CD69, OX40, and PD-1, while CD8+ T cells upregulated 4-1BB, CD25, ICOS, and OX40. Cytokine profiling showed strong induction of inflammatory mediators, with IFN-γ and TNF displaying the greatest response. Preliminary RNA analysis revealed enrichment of immune-activated, inflammatory, and cytokine-driven pathways consistent with effector engagement.\nCONCLUSIONS: These findings demonstrate the feasibility of using cryopreserved patient-derived tumoroids for ex vivo testing of bispecific T-cell engagers while preserving the native tumor-immune microenvironment. Integration of cytokine measurements, transcriptomic readouts, and immune phenotyping provides a scalable approach for characterizing mechanisms of action of MUC1-targeted agents and supports continued development of bispecific immunotherapies for solid tumors.", "source_company": "Nilogen Oncosystems", "source_org_type": "公司", "row_number": 933, "target_meta": "MUC1", "MOA_meta": "结合剂"}, {"drug_name": "claudin 18.2 peptide conjugated to proapoptotic peptide", "company": "Kyungpook National University", "org_type": "大学", "target": "Claudin 18.2", "modality": "other", "importance_level": "中", "total_score": 54.5, "institution_score": 35, "track_score": 85, "milestone_score": 45, "field_heat_score": 80, "bonus_score": 2, "brief_reason": "药物为Claudin 18.2靶向的穿膜肽连接促凋亡肽，靶点为胰腺癌和胃癌热门靶点Claudin 18.2，赛道热度较高。机构为韩国大学，处于早期研究阶段（体外+转基因小鼠模型显示生存改善），整体开发里程碑价值有限。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10792", "id": "Lp7M_5wBZznHJdnt_W7O", "source_drug_name": "claudin 18.2 peptide conjugated to proapoptotic peptide", "title": "Claudin 18.2 targeted proapoptotic peptide for early pancreatic diagnosis and tumor-target killing", "abstract_text": "Pancreatic adenocarcinoma is a lethal condition with a rising incidence, predicted to become the second leading cause of cancer-related deaths worldwide by 2030. One major hurdle in the treatment of this disease is the predominantly elderly patient population and clinically silent and aggressive nature. Early detection of pancreatic neoplasms and novel treatment for highly aggressive and metastatic conditions is of great need in pancreatic tumor therapy.Claudins are crucial components of tight junctions. They are transmembrane proteins and are the keeper of the “fence function”. Claudins in tumor are like the fall of the soldiers entrusted to protect the gate. Claudin 18.2 is a member of the claudin family, commonly expressed in multiple cancers, including Gastric cancer and Pancreatic cancer. Claudin-18.2 expression on cancer cells is increased and exposed on surface of the cells. The development of malignant tumors leads to the disruption of tight junctions, exposing the Claudin 18.2 epitope on the surface of tumor cells as a specific target. Also, claudin 18.2 is transcriptionally upregulated with the binding of cyclic AMP-responsive element binding protein to the methylated CLDN18.2 promoter region. Claudin 18.2 is considered an early stage marker of pancreatic carcinogenesis. Claudin 18.2 is considered a ‘dark horse’ in anti-tumor therapy. Thus, Claudin 18.2 could be a good “target” for early detection and target-specific treatment of pancreatic tumor.Construction of phage peptide library and bio panning for claudin18.2-binding peptides using claudin18.2 overexpressing cells : After five rounds of screening, phage titers that bind to transfected cells were enriched higher-fold compared to phage titers isolated in the first round. 2 phage clones displaying peptides that selectively bound to transfected cells were chosen and sequenced for further study. The two peptides showed selective binding to claudin 18.2 expressing cells as analyzed by Immunofluorescence. Pull down assay further confirmed selective binding of peptide to claudin 18.2. Bioaccumulation study in vivo showed significant accumulation of peptide in tumor tissue. Treatment of KPC transgenic pancreatic tumor bearing mice with claudin 18.2 peptide conjugated to proapoptotic peptide enhanced the survival of the mice. In summary, Claudin 18.2 peptide can specifically target the tumor cells and conjugation with proapoptotic peptide can induce tumor targeted apoptosis with increased survival in pancreatic tumor bearing mice. Claudin 18.2 targeted tumor killing can be a promising approach for pancreatic tumor treatment.", "source_company": "Kyungpook National University", "source_org_type": "大学", "row_number": 1157, "target_meta": "CLDN18.2", "MOA_meta": "其他"}, {"drug_name": "pHLIP-SIINFEKL", "company": "Yale School of Medicine", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "中", "total_score": 54, "institution_score": 35, "track_score": 75, "milestone_score": 55, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "pHLIP为酸性微环境靶向递送载体，负载SIINFEKL模型抗原以增强肿瘤免疫原性，机制新颖但非真实药物靶点。大学机构基础研究阶段，赛道具创新性但开发性有限，故综合重要性中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1383", "id": "hlXM_5wBX1NQZOEH-LS6", "source_drug_name": "pHLIP-SIINFEKL", "title": "Reverse engineering tumors to expression neoantigens", "abstract_text": "Many cancer types lack an immunogenic target for immune cells to detect, thereby limiting the effectiveness of immunotherapy. These immunologically “cold” tumors are marked by low neoantigen expression and minimal immune infiltration. We hypothesize that strategies that increase tumor immunogenicity such as inducing neoantigen expression or enhancing antigen presentation can convert cold tumors into “hot”, thus improving responsiveness to immune-based treatments. Using a novel pH low insertion peptide (pHLIP) that penetrates cell membranes in an acidic microenvironment, we have successfully shown tumor-targeted delivery of cargo peptides (e.g. SIINFEKL) into transplanted B16 (melanoma) and MC38 (colon adenocarcinoma) cell lines. Furthermore, SIINFEKL was proteolytically processed through the MHC-I antigen presentation pathway, induced OT-I antigen-specific T cells, and led to delayed tumor growth (Yurkevicz et al, Mol. Cell Therapy). Using a virus-induced Kras mutant p53 null (KP) mouse model of sarcoma, we tested whether pHLIP could deliver SIINFEKL into autochthonous de novo tumors and induce OT-I-specific T cells. We isolated T cells from these KP tumors and observed that only mice treated with pHLIP-SIINFEKL exhibited OT-I-specific T cell infiltration (SIINFEKL-MHC-I-Tetramer+) and effector activation (CD44+, IFNg+), indicating that pHLIP can function in a physiological context to deliver neoantigens and trigger an immunogenic response. These findings demonstrate a novel strategy to enhance sarcoma immunogenicity and may inform future immunotherapy approaches.", "source_company": "Yale School of Medicine", "source_org_type": "大学", "row_number": 927, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "PTPRE inhibitor", "company": "University of California, San Diego", "org_type": "大学", "target": "PTPRE", "modality": "inhibitor", "importance_level": "中", "total_score": 54, "institution_score": 35, "track_score": 65, "milestone_score": 70, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "PTPRE作为新型力学转导靶点，通过抑制LYN/TWIST1通路阻断基质刚度诱导的EMT和TNBC转移，机制新颖但靶点热度中等。大学机构preclinical阶段有PDX体内验证和药理抑制效果，赛道有一定创新性但非热门modality，总分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6051", "id": "9Z7M_5wBZznHJdnt_W3O", "source_drug_name": "PTPRE inhibitor", "title": "PTPRE receptor tyrosine phosphatase in matrix-stiffness-driven EMT and breast cancer metastasis", "abstract_text": "Mechanical cues from the extracellular matrix (ECM) regulate various cellular processes in cell proliferation, migration and differentiation via distinct mechanotransduction pathways. In breast cancer patients, increase in tumor tissue stiffness is correlated with distant metastasis and poor outcome. Previous studies show that, cell invasion and metastasis. Using 3D reconstituted extracellular matrixes that recapitulate the range of physiological stiffness from normal mammary glands to breast tumors, we previously reported that increased ECM stiffness promotes Epithelial-Mesenchymal Transition (EMT) and identified the TWIST1 transcription factor as a key player driving EMT and invasion in response to increasing ECM stiffness. High ECM stiffness activates the LYN tyrosine kinase, which phosphorylates TWIST1 and promotes TWIST1 to enter the nucleus, thus triggering EMT and invasion. To understand how LYN is activated at high ECM stiffness, we performed an unbiased screen for tyrosine phosphatases that is required for high stiffness-induced EMT and invasion in basal-subtype mammary cells. This screen identified a novel role of protein tyrosine phosphatase epsilon (PTPRE) in TWIST1/LYN mechanotransduction. We show that genetic deletion of PTPRE blocked high ECM stiffness-induced EMT and invasion in human and mouse TNBC cell-derived acini as well as in patient-derived triple-negative breast cancer (TNBC) organoids, demonstrating a conserved role of PTPRE in stiffness-induced invasion. Mechanistically, knockdown or pharmacological inhibition of PTPRE blocks LYN activation, TWIST1 nuclear translocation and EMT at high stiffness. Biochemical analyses and AlphaFold modeling suggest that PTPRE bind to LYN and dephosphorylates Tyr507 to activate the LYN kinase. Functionally, treatment of mice carrying TNBC PDX tumors with a PTPRE inhibitor decreased local invasion and lung metastasis. This study identifies a novel role for PTPRE in matrix-stiffness induced EMT and metastasis in TNBC and broadens the repertoire of actionable targets implicated in breast cancer metastasis. The importance of mechanical force and tissue stiffness in regulating breast cancer invasion and metastasis has only recently been appreciated. This study raises the promise to target novel mechanotransduction pathways and mechanoregulators to combat breast tumor invasion and metastasis.", "source_company": "University of California, San Diego", "source_org_type": "大学", "row_number": 1122, "target_meta": "PTPRE", "MOA_meta": "抑制剂"}, {"drug_name": "CAR-T cell therapy", "company": "Beckman Research Institute of City of Hope", "org_type": "研究机构", "target": "未披露", "modality": "CAR", "importance_level": "中", "total_score": 53.8, "institution_score": 45, "track_score": 85, "milestone_score": 35, "field_heat_score": 75, "bonus_score": 3, "brief_reason": "该CAR-T研究聚焦通过CAR priming增强TCR对低亲和力肿瘤抗原的识别，机制新颖但靶点未披露。机构为知名研究机构而非头部药企、仍处preclinical概念验证阶段导致总分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1775", "id": "jlXM_5wBX1NQZOEH-LG6", "source_drug_name": "CAR-T cell therapy", "title": "CAR priming lowers TCR activation threshold to enhance recognition of low affinity tumor antigens", "abstract_text": "Chimeric antigen receptor (CAR)-T cell therapy has shown remarkable efficacy in hematologic malignancies but has achieved limited success in solid tumors due to barriers such as immunosuppressive tumor microenvironments and poor antigen presentation1. Primary brain tumors, across pediatric and adult settings, represent a particularly difficult target: they display profound intratumoral heterogeneity, frequently downregulate MHC class I2, and often present low-avidity or subclonally expressed antigens that are poorly recognized by conventional T cell receptors (TCRs). Prior studies have reported crosstalk between CAR and TCR signaling, suggesting that TCR expression is important for optimal CAR function3, and others indicate that CAR function may be suppressed when encountering low-avidity TCR antigens4. Our preliminary data show that CAR priming enhances TCR responses against weak antigens and promotes a more memory-like, less effector-like phenotype, a state linked to improved persistence and durable tumor control. Together, these findings highlight a key gap: how CAR signaling influences TCR function in the setting of weak antigens. Addressing this question is particularly critical in brain tumors, where recognition of low-avidity and poorly presented antigens limits the efficacy of current CAR T-cell therapies.", "source_company": "Beckman Research Institute of City of Hope", "source_org_type": "研究机构", "row_number": 405, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "anti-PD1", "company": "Tianjin Medical Univ. Cancer Inst. & Hospital", "org_type": "医院", "target": "未披露", "modality": "other", "importance_level": "中", "total_score": 53.8, "institution_score": 35, "track_score": 75, "milestone_score": 55, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "摘要聚焦cPLA2α敲除增强抗肿瘤免疫并协同anti-PD1疗效，但药物本身为anti-PD1，未披露新药靶点/机制，仅为机制研究+联合潜力探索。机构为医院类型得分较低，但免疫治疗+肿瘤微环境调控赛道热度较高，显示一定协同价值。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1347", "id": "XJ7ECZ0BZznHJdntvNYd", "source_drug_name": "anti-PD1", "title": "Inhibiting intracellular cPLA2α in cervical cancer cells enhances antitumor immunity and facilitates the efficacy of anti-PD1 checkpoint immunotherapy", "abstract_text": "Immunotherapy has emerged as a breakthrough in treating cancer. However, only a limited subset of patients responds to the treatment and maintain a long-term response. Hence, there is an urgent need to explore the mechanisms of tumor resistance to immune checkpoint blockade (ICB) to identify effective targets and develop efficient combination therapies. Here, we demonstrate genetic ablation of cPLA2α in tumor cells profoundly inhibits tumor growth and prolongs survival in immunocompetent mice but shows minimal effect in immunodeficient mice, implicating the critical role of the adaptive immune system. Wild-type (WT) and cPLA2α-knockout (KO) tumors are profiled by single-cell RNA sequencing, revealing significant differences in genome-wide transcription and the presence of cancer cells, macrophages, and T cells. To elucidate the multifaceted regulatory functions of cPLA2α, we performed multiple functional perturbations, uncovering that: cPLA2α-high tumor cells drive ferroptosis-associated oxidative lipid metabolism via the SLC7A11/ALOX12 axis, leading to 12-HETE accumulation; these lipids are taken up by macrophages via GPR31 to induce M2-like polarization; concurrently, ferroptosis processes in tumor cells suppress the levels of effector factors GZMB in CD8+ T cells. Both effects exert potent immunosuppressive activity, collectively forming a barrier against T cell attack. In contrast, cPLA2α-KO cancer cells downregulate 12-HETE production, promote the polarization of MKi67+ M1-like macrophages, accompanied by upregulation of CXCL16 expression; meanwhile, cPLA2α-KO facilitates the differentiation of T cells into effector memory CD8+ T cells with elevated CXCR6 level. Cell-cell communication analysis reveals that M1-like macrophages and T cells primarily interact via the CXCL16-CXCR6 axis, which facilitates CD8+ T cell recruitment and activation. Furthermore, cPLA2α-KO increases the infiltration of effector memory CD8+ T cells into tumors, triggers CD8+ T cell-mediated control of tumor growth, enhances their cytotoxic functions (e.g., IFNG, GZMB), and reduces the proportion of naïve CD8+ T cells. Loss of cPLA2α enhances T cell proliferation, activation, and the sensitivity of tumor cells to CD8+ T cell cytotoxicity in vitro. Depleting CD8+ T cells in vivo largely rescues the tumor growth induced by cPLA2α-KO, confirming that CD8+ T cells are responsible for the antitumor effect. Notably, the cPLA2α cancer signature serves as a prognostic indicator for survival and shows an inverse correlation with T cell infiltration intensity in cervical cancers, consistent with its immunosuppressive effects, and targeting cPLA2α synergistically enhances anti-PD1 immunotherapy efficacy. Therefore, disrupting cancer cell cPLA2α-mediated immune escape may offer potential therapeutic strategies to enhance antitumor immunity.", "source_company": "Tianjin Medical Univ. Cancer Inst. & Hospital", "source_org_type": "医院", "row_number": 681, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "CBD-IL-12 expressing FAP CAR-T cells", "company": "Imperial College London", "org_type": "大学", "target": "FAP", "modality": "CAR", "importance_level": "中", "total_score": 53.5, "institution_score": 35, "track_score": 75, "milestone_score": 60, "field_heat_score": 70, "bonus_score": 6, "brief_reason": "该产品为靶向FAP的CAR-T细胞，通过NFAT调控局部释放CBD-IL-12，实现CAF清除+肿瘤局部免疫激活的双重机制。大学机构分数较低，但CAR+局部细胞因子递送在纤维化肿瘤赛道具有创新性和潜力，动物模型显示优于对照设计且安全性改善。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9398", "id": "JlXM_5wBX1NQZOEH-LK6", "source_drug_name": "CBD-IL-12 expressing FAP CAR-T cells", "title": "Next-generation CAR-T cells that target only tumor stroma and matrix: Collagen-binding IL-12-expressing FAP-CAR-T show strong anti-tumor efficacy but are safe", "abstract_text": "Fibrotic tumor subtypes have been identified across multiple solid malignancies, including pancreatic, breast, lung, and colorectal cancers. These fibrotic tumors are generally difficult-to-treat and are characterized by extensive desmoplastic stroma and pronounced heterogeneity. The fibrotic tumor microenvironment (TME) not only serves as a physical barrier that impedes therapeutic penetration and immune cell infiltration but also contributes to therapeutic resistance, rendering these cancers particularly challenging to treat. Cancer-associated fibroblasts (CAFs), which are abundant in the TME, have emerged as a promising therapeutic target. In this study, we developed a novel chimeric antigen receptor T cell (CAR-T) therapy specifically targeting fibroblast activation protein (FAP) expressed on CAFs. After binding to FAP, NFAT signalling enables the subsequent local secretion of collagen-binding domain-fused interleukin-12 (CBD-IL-12) from CAR-T cells. This CAR-T cells only remove CAF but also concentrate collagen-binding IL-12 in the tumor to enhance host immune activation within the tumor microenvironment. The CBD-IL-12 expressing FAP CAR-T cells exhibited effective cytotoxicity against fibroblast cell lines in vitro. In vivo, CBD-IL-12 expressing FAP CAR-T cells significantly suppressed tumor progression of murine breast cancer and pancreatic cancers, which were better than 2nd generation FAP CAR-T or wt IL-12-expressing CAR-T. Importantly, CBD-fusion to IL-12 in the CAR-T design improved accumulation of IL-12 within tumor tissues >10 times, whereas minimizing systemic IL-12 exposure and reducing associated toxicities. Immunophenotyping revealed increased infiltration of CD8⁺ cytotoxic T lymphocytes and reduced regulatory T cells (Tregs) in the TME of mice treated with CBD-IL-12-expressing FAP CAR-T, compared to those treated with FAP CAR-T alone or with wt IL-12 secretion. This dual-function CAR-T approach serves to first deplete CAFs, thereby disrupting the physical barrier impeding immune cell infiltration, and second, to activate anti-tumor immunity through localized IL-12 delivery. We have created a new therapeutic concept, which utilizes CAR-T cells for non-tumor antigen target, but still activates immune cells locally in the tumors, which could be a universal purpose CAR-T cells for multiple cancer types, especially for fibrotic or post-x-ray tumors.", "source_company": "Imperial College London", "source_org_type": "大学", "row_number": 26, "target_meta": "FAP", "MOA_meta": "其他"}, {"drug_name": "BCMA-targeted CAR-T cell therapy", "company": "ATCC", "org_type": "公司", "target": "BCMA", "modality": "CAR", "importance_level": "中", "total_score": 53.5, "institution_score": 35, "track_score": 85, "milestone_score": 45, "field_heat_score": 75, "bonus_score": 0, "brief_reason": "靶向BCMA的CAR-T细胞疗法，BCMA是多发性骨髓瘤高度验证靶点，CAR赛道整体热度高。ATCC作为工具/细胞系提供商而非药物研发主体，开发阶段为体外方法学研究而非药物推进，综合重要性中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9381", "id": "3VXM_5wBX1NQZOEH-LK6", "source_drug_name": "BCMA-targeted CAR-T cell therapy", "title": "Evaluation of ex vivo CAR-T cell cytotoxicity and infiltration using multimodal 2-D and 3-D imaging approaches", "abstract_text": "Background: Chimeric antigen receptor T (CAR-T) cell therapy has revolutionized cancer treatment, particularly for hematologic malignancies. Beyond CD19 and CD20, BCMA (B-cell maturation antigen)-targeted CAR-T therapies have become a major focus, especially for multiple myeloma. In fact, BCMA is considered one of the most validated targets in plasma cell malignancies. In pursuit of improving the efficacy and number of applications of this therapy, sensitive and robust cytotoxicity assays are required to efficiently evaluate different CAR constructs, effector-to-target cell ratios, and immune effector cells ex vivo. Furthermore, as CAR-T cell therapy is now under active investigation for the treatment of solid tumors, there is an urgent need for models that mimic the complexity of 3-D tumor environments.\nMethods and results: In this study, we engineered two luciferase-GFP dual reporter cancer cell lines, Raji-GFP-Luc2 and NCI-H929-GFP-Luc2, and demonstrated their use in a streamlined combined bioluminescence and live imaging assay. Notably, Raji-GFP-Luc2 and NCI-H929-GFP-Luc2 endogenously express high levels of the two FDA-approved CAR-T target antigens, CD19 and BCMA, respectively. Using these lines in co-culture with mock and targeting CAR-T cells, we tracked reporter cancer and CAR-T cell interactions by fluorescence live imaging. Fluorescence quantification clearly demonstrated that CAR-T cells killed cancer cells at higher levels compared to mock controls in both 2- and 3-D co-culture. We then evaluated dose-dependent cancer cell killing by targeting CAR-T cells in 2- and 3-D by luciferase assay. Importantly, we found that quantification of either transgene yields comparative results despite utilizing distinct assays and readouts. Finally, we embedded reporter cancer cell spheroids in 3-D matrices and performed time-lapse imaging of CAR-T cell infiltration. Bioluminescence assay of the embedded spheroids confirmed increased cancer cell killing by targeting CAR-T cells in a solid tumor model.\nConclusions: Overall, our dual reporter cancer cell lines are powerful and effective tools for assaying CAR-T cell cytotoxicity. Furthermore, our multimodal imaging platform integrates bioluminescence and live fluorescence imaging to quantitatively and visually assess CAR-T cell cytotoxicity. With scalability and sensitivity, this assay provides an avenue for standardizing CAR-T cytotoxicity testing and will aid in the expansion and improvement of this promising therapy.", "source_company": "ATCC", "source_org_type": "公司", "row_number": 47, "target_meta": "BCMA", "MOA_meta": "其他"}, {"drug_name": "UGT8 inhibitor", "company": "UT MD Anderson Cancer Center", "org_type": "医院", "target": "UGT8", "modality": "inhibitor", "importance_level": "中", "total_score": 53.5, "institution_score": 35, "track_score": 75, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 2, "brief_reason": "靶向UGT8抑制硫酸脑苷脂代谢，破坏胰腺癌前病变IPMN细胞线粒体稳态，显示抑制肿瘤生长的preclinical潜力。机构为顶级癌症医院但非商业药企，赛道为肿瘤代谢热门靶点，整体preclinical阶段有较强机制验证和in vivo数据。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9115", "id": "T1XM_5wBX1NQZOEH-LO6", "source_drug_name": "UGT8 inhibitor", "title": "Targeting sulfatide metabolism as a therapeutic vulnerability in pancreatic pre-cancer lesions", "abstract_text": "Asymptomatic precursor lesions that predate invasive pancreatic ductal adenocarcinoma (PDAC) by years provide a compelling opportunity for cancer interception. One such precursor is the intraductal papillary mucinous neoplasm (IPMN). Using Matrix-Assisted Laser Desorption/Ionization Mass Spectrometry (MALDI-MS) imaging and spatial transcriptomics, we discovered long-chain hydroxylated sulfatide species and their biosynthetic enzymes as selectively enriched in IPMN. Genetic ablation of UGT8 and Gal3st1, the key enzymes catalyzing the synthesis of the sulfatide precursor galactosylceramide (GalCer) and sulfatides, respectively, suppressed sulfatide production and triggered mitochondrial ceramide accumulation in mutant Kras;Gnas IPMN cells. These metabolic disruptions led to reduced proliferation and invasiveness, alongside increased caspase-dependent apoptosis. Pharmacologic UGT8 inhibition also caused profound impairments in mitochondrial function and morphology. Integrated lipidomic and proteomic analyses on mitochondrial fractions revealed remodeling of lipid composition and dysregulation of proteins involved in mitochondrial translation, oxidative phosphorylation, mitophagy and sphingolipid metabolism, corroborating the phenotypic changes observed in our functional studies. In vivo, UGT8 inhibition suppressed tumor growth in IPMN allograft models. Collectively, our findings identify enhanced sulfatide metabolism as an early metabolic alteration of cystic pre-cancerous lesions and demonstrate that targeting UGT8 perturbs mitochondrial homeostasis and function, revealing a potential strategy for pancreatic cancer interception.", "source_company": "UT MD Anderson Cancer Center", "source_org_type": "医院", "row_number": 52, "target_meta": "UGT8", "MOA_meta": "抑制剂"}, {"drug_name": "a novel PD-1 inhibitor", "company": "PharmaLegacy Laboratories", "org_type": "公司", "target": "PD-1", "modality": "inhibitor", "importance_level": "中", "total_score": 53.5, "institution_score": 45, "track_score": 85, "milestone_score": 35, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "药品为新型PD-1抑制剂，靶点PD-1为经典热门免疫检查点，modality为inhibitor但摘要实际聚焦于ADC耐药平台而非具体药物披露。该研究由CRO机构PharmaLegacy主导，属preclinical平台构建，无明确药物开发里程碑，机构非头部药企导致总分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5018", "id": "Tp7M_5wBZznHJdnt_W7P", "source_drug_name": "a novel PD-1 inhibitor", "title": "Overcoming acquired and intrinsic resistance with an integrated ADC platform", "abstract_text": "Antibody-drug conjugates (ADCs) emerged as a transformative class of targeted therapeutics, reforming the treatment landscape for a growing number of malignancies by integrating benefits from the specificity of antibodies and the potent cytotoxicity of payloads. Despite the remarkable clinical successes, development of acquired and intrinsic resistance poses a fundamental challenge limiting the long-term potential in a considerable proportion of patients. Various mechanisms have been reported to cause ADC resistance, including alterations in target antigen, impaired ADC internalization, efflux of the cytotoxic payload, dysregulation of lysosomal function and insensitivity to payload etc. Elucidating this complex biology is crucial for developing novel ADCs, identifying biomarkers for patient stratification and exploring strategies to overcome resistance. This is not only a scientific need but also an important clinical imperative.\nThe current study describes an integrated platform recapitulating different clinical scenarios of ADC resistance. Models with acquired resistance were developed by either long-term in vivo induction on responsive CDX models or by establishing PDX from post-treatment relapsed patient tumors. Models with intrinsic resistance were first identified by screening ADC responses across a panel of target-positive models, followed by subsequent mechanism studies, such as PD examination, sequencing and ex vivo analysis. An Her2- and Trop2-positive gastric PDX shown clear resistance (TGI < 10%) to trastuzumab deruxtecan and sacituzumab govitecan, two clinically used Her2 and Trop2 ADCs respectively, limited response (TGI 10-30%) to Herceptin and no response to Dxd treatment. This result suggests its intrinsic resistance is largely due to the unresponsiveness to payload end. Further study on double-humanized PDX (PDX established on humanized mice) shown significant tumor growth inhibition (TGI > 65%) when treated with anti-PD1 antibody, implicating the clinical benefit of combining immune checkpoint inhibitors with ADCs.\nIn addition to in vivo models featuring ADC resistance, multiple in vitro platforms were established to enable rapid assessment of ADC in terms of sensitivity and toxicity. A tissue culture assay using clinical samples allows ADC evaluation and comparative screening of combination strategies over a panel of patient tumors. In addition, the well-known ocular toxicity associated with multiple clinically used ADCs can be recapitulated by a cell-based assay using human corneal epithelial cells. On this platform, belantamab mafodotin, trodelvy and T-DM1 demonstrated consistent high, medium and low cytotoxicity respectively.\nThe integration of above-mentioned platforms facilitates a deep understanding of resistance mechanisms and promotes the development of ADCs that are better aligned with clinical needs, with the ultimate goal of overcoming resistance.", "source_company": "PharmaLegacy Laboratories", "source_org_type": "公司", "row_number": 99, "target_meta": "PD1", "MOA_meta": "抑制剂"}, {"drug_name": "HSV-1(VC2) GM-CSF", "company": "Louisiana State University", "org_type": "大学", "target": "未披露", "modality": "oncolytic virus", "importance_level": "中", "total_score": 53.5, "institution_score": 35, "track_score": 75, "milestone_score": 55, "field_heat_score": 65, "bonus_score": 2, "brief_reason": "HSV-1(VC2)为基因工程溶瘤病毒表达GM-CSF，通过溶瘤和免疫激活机制与吉西他滨协同抗PDAC。大学机构分数较低，但溶瘤病毒赛道热度较高，体外/体内显示协同抑瘤和减转移有一定preclinical强度，总分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5139", "id": "j57M_5wBZznHJdnt_W7P", "source_drug_name": "HSV-1(VC2) GM-CSF", "title": "Oncolytic virus-chemotherapy combination improves control of PDAC growth and spread", "abstract_text": "Pancreatic ductal adenocarcinoma (PDAC) remains one of the deadliest solid tumors. Its progression is driven by KRAS-dependent signaling, a dense desmoplastic stroma, early metastatic spread, and an immunologically ‘cold’ tumor microenvironment (TME). Therapies that combine direct cytotoxic activity with TME reprogramming may improve treatment response. Oncolytic virotherapy offers such a dual mechanism.We hypothesize that a genetically engineered herpes simplex virus (HSV-1) strain, HSV-1(VC2), engineered to express murine GM-CSF, can synergize with gemcitabine by modulating tumor-intrinsic signaling and initiating early steps toward a more immune-responsive TME. In vitro studies using murine KRASG12D TP53R172H Cre (KPC) cells demonstrated a strong synergistic interaction between the proposed oncolytic virus (oV) and gemcitabine, as supported by ZIP synergy modeling. qPCR analysis showed that gemcitabine increased EMT-associated transcripts (TGF-β, fibronectin, TAZ) as well as pro-survival/pro-migratory transcripts (CAV1, AKT, CTNNB1, PI3K). The oV alone activated STING-associated innate immune pathways. The combination treatment suppressed gemcitabine-induced EMT and proliferative signaling while maintaining antiviral and immunostimulatory gene expression, indicating coordinated transcriptional modulation consistent with enhanced cytotoxic and immunogenic activity.To evaluate in vivo relevance, we used an orthotopic immunocompetent PDAC model in which 104 KPC cells were surgically implanted into the pancreas of WT C57BL/6 mice. This model reflects PDAC growth kinetics and metastatic behavior. In preliminary studies, oncolytic virotherapy alone did not reduce tumor size but markedly reduced liver metastasis, with 1 of 4 mice showing liver involvement compared to 4 of 4 in the control group at day 38. In another study, the same OV application schedule (administered on days 10 and 24 after tumor implantation) was used together with gemcitabine (given weekly starting on day 11 at 100 mg/kg). This combination further decreased primary tumor burden compared with either monotherapy at the 38-day endpoint (n=8 mice/group). A Panc-1 xenograft model showed similar patterns in primary tumor reduction and metastatic spread.Ongoing work includes flow cytometry, targeted transcriptomics, and proteomic profiling to define immune and molecular contributors to synergy. Additionally, in vitro studies using human PDAC and pancreatic stellate cell 3D co-cultures, as well as human PDAC organoids, are in progress. Together, these findings position HSV-1(VC2) GM-CSF as a clinically relevant partner for gemcitabine and a potential strategy to improve PDAC responsiveness through both cytotoxic and immune-mediated effects.", "source_company": "Louisiana State University", "source_org_type": "大学", "row_number": 104, "target_meta": "not available", "MOA_meta": "溶瘤病毒"}, {"drug_name": "MMPins", "company": "Emory University", "org_type": "大学", "target": "MKK3/MYC PPI", "modality": "inhibitor", "importance_level": "中", "total_score": 53.5, "institution_score": 35, "track_score": 75, "milestone_score": 55, "field_heat_score": 70, "bonus_score": 4, "brief_reason": "MMPins为小分子抑制剂，靶向MKK3/MYC蛋白相互作用以破坏MYC稳定性并逆转耐药，主要由Emory大学学术机构开发。虽靶点机制新颖且MYC驱动癌症需求大，但机构非商业公司且仍处早期筛选阶段，整体重要性中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8890", "id": "H1XM_5wBX1NQZOEH-LG5", "source_drug_name": "MMPins", "title": "Targeting the MKK3/MYC protein-protein interaction to overcome drug resistance in MYC-driven cancers", "abstract_text": "MYC is a central oncogenic transcription factor that drives tumor progression in multiple cancer types, including triple-negative breast cancer (TNBC) and non-small cell lung cancer (NSCLC). However, direct MYC inhibition remains highly challenging due to its intrinsically disordered structure and lack of defined drug-binding pockets. We uncovered a novel mechanism of MYC activation through a direct protein-protein interaction (PPI) with mitogen-activated protein kinase kinase 3 (MKK3). Integrative bioinformatics analyses using our AVERON platform revealed that elevated levels of the MKK3/MYC complex significantly correlate with poor clinical outcomes in TNBC and lung cancer, particularly in patient subsets with high MYC dependency.\nTo define the functional consequences of the PPI, we combined genetic perturbation, chemical biology, and clinical genomics analyses. MKK3 silencing reduced the viability of TNBC and NSCLC cells, and these effects were recapitulated with small-molecule MKK3/MYC PPI inhibitors (MMPins), identified through our TR-FRET ultra-high-throughput screening campaign. Disruption of the MKK3/MYC PPI destabilized MYC and suppressed MYC-driven transcriptional programs. Furthermore, MKK3/MYC PPI inhibition is correlated with the downregulation of lactate dehydrogenase A (LDHA), a key mediator of glycolytic reprogramming and a well-established driver of drug resistance. In TNBC models, MKK3/MYC PPI inhibition reduced LDHA expression and blocked the glycolytic flux that fuels MYC-dependent growth. In NSCLC, MMPins restored apoptotic sensitivity in EGFR TKI-resistant cells and, when combined with osimertinib, significantly suppressed tumor growth in vivo.\nTogether, these findings define the MKK3/MYC PPI as a mechanistic driver of LDHA-mediated metabolic adaptation and drug resistance. Pharmacological disruption of this interaction offers a promising therapeutic strategy to suppress MYC-dependent oncogenic networks, reverse resistance phenotypes, and improve outcomes in MYC-driven cancers.\nAcknowledgments: This work was supported in part by the Emory Center for New Medicines Therapeutic Advancement Award (A.A.I), Mary Kay Foundation Grant for Cancer Research (A.A.I), the NCI’s Informatics Technology for Cancer Research (ITCR) Program (R21CA274620, A.A.I.), NCI Emory Lung Cancer SPORE (P50CA217691, H.F.), NCI P01CA257906 (H.F.), Career Enhancement Program (A.A.I., P50CA217691), Winship Cancer Institute (NIH 5P30CA138292). We thank the Emory University Undergraduate Research Program in Biology.", "source_company": "Emory University", "source_org_type": "大学", "row_number": 331, "target_meta": "MKK3,MYC", "MOA_meta": "抑制剂"}, {"drug_name": "a PLD1 inhibitor", "company": "Asan Medical Center, University of Ulsan College of Medicine", "org_type": "医院", "target": "PLD1", "modality": "inhibitor", "importance_level": "中", "total_score": 53.5, "institution_score": 35, "track_score": 65, "milestone_score": 70, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "靶点为PLD1，通过抑制克服卵巢癌铂耐药并增强顺铂疗效，机制新颖且preclinical数据较强，包括多种耐药模型和PDX体内验证。机构为韩国顶级医院，赛道为耐药逆转靶向小分子抑制剂热度中等偏上，总分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4017", "id": "M57ECZ0BZznHJdntvNYd", "source_drug_name": "a PLD1 inhibitor", "title": "Targeting phospholipase D1 overcomes platinum resistance and enhances cisplatin efficacy in ovarian cancer", "abstract_text": "Background: Platinum-based chemotherapy is the standard treatment for high-grade serous ovarian cancer (HGSOC), yet the development of platinum resistance remains a major barrier to effective therapy. Phospholipase D1 (PLD1) has been implicated in tumor progression and stress response pathways, but its potential as a therapeutic target in platinum-resistant ovarian cancer (OC) has not been clearly defined. This study investigated whether targeting PLD1 can restore platinum sensitivity and improve therapeutic efficacy in resistant disease.\nMethods: The impact of PLD1 inhibition was evaluated using OC cell lines, patient-derived primary tumor cells, and both cell line-derived and patient-derived xenograft models. Functional assays measured clonogenic survival, proliferation, invasion, sphere formation, apoptosis, and DNA damage. Cisplatin responsiveness was assessed following genetic PLD1 knockdown or treatment with a PLD1 inhibitor.\nResults: PLD1 suppression significantly reduced survival, proliferation, and invasiveness in platinum-resistant OC cells, while inducing apoptosis and accumulation of DNA damage. Importantly, PLD1 inhibition restored cisplatin sensitivity across multiple resistant models, leading to a marked reduction in clonogenic survival. In vivo, combined PLD1 inhibition and cisplatin treatment markedly suppressed tumor growth, prolonged survival, and reduced metastatic burden in xenograft and PDX models, with greater therapeutic benefit observed in platinum-resistant tumors.\nConclusions: PLD1 is a key survival determinant in platinum-resistant OC and contributes directly to treatment failure. Targeting PLD1 enhances the antitumor efficacy of cisplatin and provides strong preclinical rationale for PLD1-directed combination therapy in refractory HGSOC.", "source_company": "Asan Medical Center, University of Ulsan College of Medicine", "source_org_type": "医院", "row_number": 365, "target_meta": "PLD1", "MOA_meta": "抑制剂"}, {"drug_name": "anti-GARP", "company": "Icahn School of Medicine at Mount Sinai", "org_type": "大学", "target": "GARP", "modality": "inhibitor", "importance_level": "中", "total_score": 53.5, "institution_score": 35, "track_score": 75, "milestone_score": 60, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "anti-GARP为靶向GARP的抑制剂，主要阻断Treg细胞介导的TGF-β释放以逆转免疫抑制，在MASH-HCC模型中优于抗PD-L1+抗VEGFA治疗并延长生存。机构为大学非商业研发得较低分，靶点GARP在肿瘤免疫抑制领域有热度且preclinical显示较好里程碑价值，总分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11533", "id": "jfTW_5wBLOutsWDvgbHs", "source_drug_name": "anti-GARP", "title": "Anti-GARP reverts immune suppression and extends overall survival in a MASH-HCC murine model resistant to anti-PDL1+anti-VEGFA therapy", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Icahn School of Medicine at Mount Sinai", "source_org_type": "大学", "row_number": 372, "target_meta": "CNGB1,GARP", "MOA_meta": "抑制剂"}, {"drug_name": "GalNAc-STAT3", "company": "Nanyang Technological University Singapore", "org_type": "大学", "target": "STAT3", "modality": "ASO", "importance_level": "中", "total_score": 53.5, "institution_score": 35, "track_score": 75, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "GalNAc偶联的siRNA靶向沉默STAT3，在MASH向HCC进展的早期阶段显示显著预防肿瘤发生作用，揭示了STAT3的时序依赖性。大学机构得分较低，但ASO+肝靶向+肝癌早期干预赛道有一定热度，动物模型中preclinical证据清晰但非突破性新机制。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6721", "id": "Y1XM_5wBX1NQZOEH-LG5", "source_drug_name": "GalNAc-STAT3", "title": "Temporal dependency of STAT3 signaling dictates hepatocarcinogenesis in metabolic dysfunction-associated steatohepatitis", "abstract_text": "Background: Metabolic dysfunction-associated steatohepatitis (MASH) is rapidly surpassing viral and alcoholic etiologies as the leading cause of hepatocellular carcinoma (HCC). Despite so, the molecular checkpoints governing the transition from metabolic injury to malignancy remain poorly understood. Hyperactivated STAT3 has been implicated in lipid dysregulation, inflammation, fibrosis, and oncogenic signaling. However, its dynamic regulation during MASH-to-HCC progression remains undefined.\nMethods: We performed longitudinal profiling of diseased mouse and human liver tissues to map STAT3 signaling dynamics across disease stages. Using the STAM model, we administered a hepatocyte-targeting, GalNAc-conjugated Dicer-substrate siRNA (GalNAc-STAT3) to selectively silence STAT3 at distinct disease phases: (i) early MASH and (ii) post-tumor initiation. Disease outcomes were evaluated using histopathology and serum proteomics. Spatial transcriptomics and immune phenotyping were used to resolve microenvironment- and subtype-specific responses.\nResults: STAT3 suppression exhibited striking stage-specific effects. Early intervention prior to malignant transformation substantially reduced HCC initiation and tumor burden despite persistent steatosis, demonstrating that lipid accumulation alone is insufficient to drive carcinogenesis. Multi-omics analyses identified a STAT3-dependent, TGF-β1-associated fibrogenic and inflammatory program in peritumoral regions that acted as a key molecular driver for malignant progression. In contrast, late intervention failed to reduce tumor nodule formation despite effect STAT3 inhibition, indicating loss of STAT3 dependency following malignant transformation. Spatial interrogation further revealed subtype-specific adaptive remodeling through metabolic re-differentiation in glutamine synthetase (GS)-positive nodule, and activated stress tolerance transcriptional programs in GS-negative tumors.\nConclusions: This work uncovers a previously unrecognized temporal dependency of STAT3 during MASH-associated hepatocarcinogenesis. STAT3 is essential as an early driver in establishing pro-tumorigenic niche, but is dispensable once malignant cell states emerge. These discoveries redefine the therapeutic window for STAT3 inhibition, positioning it as an early stage interception strategy rather that treatment for advanced tumors.", "source_company": "Nanyang Technological University Singapore", "source_org_type": "大学", "row_number": 382, "target_meta": "STAT3", "MOA_meta": "反义疗法"}, {"drug_name": "anti-HER2 CAR mRNA/LNPs", "company": "University of Melbourne", "org_type": "大学", "target": "HER2", "modality": "mRNA", "importance_level": "中", "total_score": 53.5, "institution_score": 35, "track_score": 85, "milestone_score": 45, "field_heat_score": 75, "bonus_score": 4, "brief_reason": "利用mRNA/LNP实现体内多免疫细胞（髓系、NK、T）同时表达anti-HER2 CAR，在实体瘤模型中显示协同抗瘤效应，具有新机制和多细胞工程亮点。机构为大学导致institution_score偏低，但赛道（in vivo CAR-mRNA+多细胞编程）热度高，preclinical数据清晰且有协同增强证据。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5217", "id": "p1XM_5wBX1NQZOEH-LG6", "source_drug_name": "anti-HER2 CAR mRNA/LNPs", "title": "In vivo CAR mRNA engineering of both adaptive and myeloid cells enables potent anti-tumor control of solid cancers", "abstract_text": "Background: In solid tumors, chimeric antigen receptor (CAR) T cell therapies are limited by their inability to overcome poor trafficking, antigen heterogeneity and the immunosuppressive myeloid cells in the tumor microenvironment (TME). Here, we introduce in vivo multi-immune cell programming designed to precisely and simultaneously program multiple immune cell types using a single engineered product. This approach builds on the clinical experience with in vivo CAR-mRNA engineered CAR myeloid cells that created a pro-inflammatory tumor environment. Combining non-targeted and targeted LNP delivery, optimized mRNA, and cell-specific CAR architecture, we endow myeloid cells, NK cells and T cells with tailored effector functions.\nMethods: Anti-HER2 CAR mRNAs optimised for myeloid, NK or T cell signalling were encapsulated in LNPs and delivered intravenously. Anti-tumor efficacy was evaluated in immunocompetent hHER2 transgenic mice bearing syngeneic hHER2-MC38 colon adenocarcinoma tumors.\nResults: In a colorectal tumor model, myeloid- and NK-cell reprogramming with CAR mRNA/LNPs drove tumor regression, prolonged survival, remodeling of the tumor microenvironment, greater antigen presentation, and enhanced T-cell infiltration and activation. Likewise, T cell engineered with CAR mRNA/tLNPs elicited robust anti-tumor activity. Notably, co-delivery of cell-specific CAR mRNA/LNPs to both myeloid and T-cell compartments produced even stronger tumor control, highlighting the power of coordinated multi-lineage immune engineering.\nConclusions: This work demonstrates that simultaneous In vivo engineering of myeloid cells, T cells, and NK cells with CARs can orchestrate the coordinated actions of both innate and adaptive immunity for potent anti-tumor activity. This strategy offers a scalable and off-the-shelf approach for cell therapy and establishes a new therapeutic paradigm for overcoming the complexity of solid tumors.", "source_company": "University of Melbourne", "source_org_type": "大学", "row_number": 429, "target_meta": "HER2", "MOA_meta": "其他"}, {"drug_name": "arecoline hydrobromide", "company": "UT MD Anderson Cancer Center", "org_type": "医院", "target": "ACAT1", "modality": "inhibitor", "importance_level": "中", "total_score": 53.5, "institution_score": 35, "track_score": 65, "milestone_score": 70, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "药品为ACAT1抑制剂，靶向酮体代谢通路以破坏前列腺癌代谢适应和肿瘤生长。机构为顶级癌症中心但非商业药企得较低分，赛道为代谢靶向治疗有一定热度，摘要显示体外+体内PDX模型显著抑瘤达preclinical较强阶段，总分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9172", "id": "x1XM_5wBX1NQZOEH-LG6", "source_drug_name": "arecoline hydrobromide", "title": "Exploiting ketone body metabolism as a therapeutic vulnerability in prostate cancer", "abstract_text": "Prostate cancer (PCa) progression remains a major clinical challenge with limited therapeutic options, and the complexity of metabolic pathways fueling advanced PCa rests poorly understood. We have identified a shift from glycolysis to ketone body (KB) metabolism in castration-resistant PCa (CRPC), with an upregulation of ketolytic/ketogenic enzymes. From these, ACAT1 is a potential therapeutic candidate, as its expression is elevated in aggressive PCa and associates with unfavorable clinical outcomes. Here, we investigated the contribution of the bone niche -the dominant PCa metastatic site- to KB metabolism during PCa progression and evaluated ACAT1 inhibition as a treatment strategy for advanced disease. Co-culture experiments between PCa cells and bone progenitors (MC3T3, Raw264.7) were used to evaluate bone-driven metabolic adaptations. To validate in vivo the effect of the bone niche, we implanted MDA PCa patient-derived xenograft (PDX) 183 either intrafemorally (i.f.) or subcutaneously (s.c.) in sham or castrated CB17 SCID mice. We assessed cell viability in PCa cells lines and in PDX-derived organoids (PDX.DO), treated with increasing concentrations of ACAT1 inhibitor, arecoline hydrobromide (AH). ACAT1 and phospho-ACAT1 levels were measured by Western blot and immunofluorescence. Intracellular KB and ATP content were quantified by luciferase-based assays. Lipid uptake and accumulation were quantified by flow cytometry using Bodipy probes. In vivo, mice bearing MDA PCa PDXs 183, 203 and 173 were treated with AH (50 mg/kg/day i.p., 21 days). Tumor volume, KB content, and ACAT1 modulation were evaluated. We observed transcriptional activation of lipid and KB metabolism in PC3 cells from PCa-bone co-cultures, and consistently, in i.f. PDXs compared to matched s.c. tumors, alongside a significant increase in ACAT1 expression levels. Castration dynamically modulated ACAT1 levels in MDA PCa 183 tumors growing i.f., with initial downregulation followed by restoration over time, underscoring KB metabolism as a mechanism of resistance within the bone niche. Functional studies showed that AH treatment reduced cell viability in PC3, C42B, and 22Rv1 cells, as well as PDX.DO, decreased ACAT1 and phospho-ACAT1 expression, lowered KB levels, and altered lipid dynamics by increasing lipid accumulation, uptake, and decreasing ATP content (P<0.05). In vivo, AH treatment in MDA PCa 183 tumors led to a significant reduction in tumor volume and intratumoral KB content (P<0.05). Moreover, in the CRPC model MDA PCa 203 -derived from a longitudinal sample of the same patient as 183-, and in the aggressive hormone-naïve model MDA PCa 173, AH treatment significantly reduced both tumor volume and KB content (P<0.05). In conclusion, our findings reveal KB metabolism as a critical vulnerability in PCa progression, with ACAT1 emerging as a druggable target whose inhibition disrupts tumor growth and metabolic fitness.", "source_company": "UT MD Anderson Cancer Center", "source_org_type": "医院", "row_number": 451, "target_meta": "ACAT1,SOAT1", "MOA_meta": "抑制剂"}, {"drug_name": "TM4SF1-directed CAR-T cells", "company": "University of California, San Francisco", "org_type": "大学", "target": "TM4SF1", "modality": "CAR", "importance_level": "中", "total_score": 53.5, "institution_score": 35, "track_score": 80, "milestone_score": 55, "field_heat_score": 65, "bonus_score": 0, "brief_reason": "TM4SF1作为胆道肿瘤新型表面靶点，CAR-T体外和体内模型显示显著抑瘤活性。大学机构基础研究阶段，得分受机构类型限制但赛道热度较高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4053", "id": "6VXM_5wBX1NQZOEH-LG6", "source_drug_name": "TM4SF1-directed CAR-T cells", "title": "TM4SF1 as a novel tumor-associated antigen in biliary tract cancers targetable by immune effector cell therapy", "abstract_text": "Biliary tract cancers (BTC) are a rare set of genetically heterogeneous and aggressive malignancies associated with late presentation, poor prognosis and limited effective therapies. Thus, there is an unmet clinical need for the development of novel therapeutic strategies. Identification of uniquely expressed cell-surface tumor-associated antigens (TAA) holds promise in epithelial tumors more generally, as they can serve as ligands for a variety of therapeutics, including CAR-T cell therapy. However, TAA identification in BTCs has been limited by expression in normal liver tissue. Here, we identify the cell-surface protein transmembrane 4 L six family member 1 (TM4SF1) as a potential BTC TAA targetable by CAR-T therapy. We find TM4SF1 expression is upregulated in BTC relative to normal hepatic/biliary tissue at the mRNA level in the TCGA dataset. Correspondingly, we find that TM4SF1 in primary BTC archival tissue is upregulated at the protein level using immunohistochemistry. To validate TM4SF1 as a targetable TAA in BTC, we show that TM4SF1-directed CAR-T cells demonstrate robust, dose-dependent growth inhibition of human-derived BTC cell lines in vitro and significant anti-tumor activity in a heterotopic BTC cell line-derived xenograft model in vivo. Together, our data provide support for TM4SF1 as a promising TAA in BTCs that can be used for the rational development of therapeutic modalities targeting TM4SF1, including CAR-T cells, in a patient population with significant unmet need.\n*Authors contributed equally", "source_company": "University of California, San Francisco", "source_org_type": "大学", "row_number": 472, "target_meta": "TM4SF1", "MOA_meta": "其他"}, {"drug_name": "Antibody-drug conjugate immuno-oncology panel", "company": "NeoGenomics Laboratories", "org_type": "公司", "target": "未披露", "modality": "other", "importance_level": "中", "total_score": 53.5, "institution_score": 55, "track_score": 70, "milestone_score": 35, "field_heat_score": 65, "bonus_score": 0, "brief_reason": "该产品为NeoGenomics的Paletrra™多重免疫荧光平台上的新型抗体panel，用于表征ADC常见靶点（如B7-H3、B7-H4、TROP2等）的空间表达和肿瘤微环境，非真实药物而是支持ADC开发的工具性试剂盒。机构为专业CRO/CDx公司而非头部药企、开发阶段为工具研发而非药物milestone、ADC赛道本身热度高但本品仅为辅助工具导致总分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11160", "id": "_VXM_5wBX1NQZOEH-LG6", "source_drug_name": "Antibody-drug conjugate", "title": "Antibody-drug conjugate immuno-oncology panel for comprehensive characterization of the tumor and associated microenvironment", "abstract_text": "Antibody-drug conjugates (ADCs) represent a rapidly advancing class of targeted therapeutics that integrate the specificity of monoclonal antibodies with the potent cytotoxicity of small-molecule drugs. By coupling antibodies to highly active payloads through linkers, ADCs enable selective delivery of cytotoxic agents to tumor cells while minimizing systemic toxicity. Pivotal studies have shown compelling evidence that this strategy of anti-cancer therapeutics can dramatically improve outcomes for patients. Despite notable success, challenges such as tumor heterogeneity and predicting clinical efficacy have been difficult to overcome. Because ADCs rely on precise spatial localization of target antigens to optimize treatment efficacy, subcellular resolution of protein expression is required. To provide insight into spatial patterns and heterogeneity within a tumor, we used the Paletrra™ (NeoGenomics Laboratories, Inc) platform. Paletrra™ is a proprietary multiplex immunofluorescence (mIF) platform for the visualization and characterization of up to 60 protein biomarkers in a single FFPE section and offers high-resolution spatial and quantitative analysis of protein expression in tissue samples. Herein we report the design and use of a novel panel of commercially available antibodies to support ADC development in lung and breast cancer samples. The panel can measure common ADC targets such as B7-H3, B7-H4, c-MET, EGFR, HER2, HER3, and TROP2 combined with a membrane marker to enable subcellular differentiation between membrane and cytoplasmic expression. Quantitative image analysis enables normalization of protein expression and computation of membrane-to-cytoplasmic expression ratio, providing enhanced biological context. Moreover, because ADCs have been shown to modulate the tumor immune microenvironment, additional markers in the panel provide insight into immunogenicity, cellular relationships, and overall structural biology within the tumor samples. Application of this assay supports translational research and clinical development of ADCs, facilitating identification of patients with optimal target expression and localization.", "source_company": "NeoGenomics Laboratories", "source_org_type": "公司", "row_number": 485, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "hypoimmunogenic human regulatory T cells (Tregs)", "company": "Baylor College of Medicine", "org_type": "大学", "target": "未披露", "modality": "CAR", "importance_level": "中", "total_score": 53.5, "institution_score": 35, "track_score": 85, "milestone_score": 45, "field_heat_score": 80, "bonus_score": 0, "brief_reason": "该产品为基因工程化的同种异体调节性T细胞（Tregs），通过CRISPR敲除B2M、TCRα/β和SRC-3实现低免疫原性，主要用于预防移植物抗宿主病和移植排斥。机构为大学非商业研发、仍处preclinical机制研究阶段导致总分偏中，但细胞治疗+同种异体Treg赛道热度较高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3859", "id": "SVXM_5wBX1NQZOEH-LK6", "source_drug_name": "hypoimmunogenic human regulatory T cells (Tregs)", "title": "CRISPR-Cas engineering of allogeneic regulatory T cells reveals an essential role for steroid receptor coactivator 3 (SRC-3) in maintaining FOXP3 expression and suppressive function", "abstract_text": "Genetically engineered allogeneic regulatory T cells (Tregs) represent a promising off‑the‑shelf therapy to prevent graft‑versus‑host disease and transplant rejection, but their clinical utility is constrained by immune rejection and alloreactivity. Using CRISPR-Cas editing, we generated hypoimmunogenic human Tregs through multiplex knockout of B2M (reducing HLA class I), TCRα/β (eliminating receptor‑mediated alloreactivity), and SRC‑3 (a transcriptional coactivator linked to Treg stability). In prior murine studies, SRC‑3 disruption enhanced tumor clearance, but in human Tregs, its deletion impaired suppressive function, underscoring SRC‑3’s role in maintaining lineage identity. Functionally, SRC‑3 knockout Tregs failed to suppress effector T cell proliferation, a defect mirrored in triple knockout (TCR+B2M+SRC‑3) cells. Co‑culture with unedited Tregs restored suppression, suggesting functional compensation. FOXP3 protein levels were markedly reduced in SRC‑3 and triple knockout Tregs, consistent with destabilized lineage commitment. These findings highlight SRC‑3, TCR, and B2M as central regulators of transcriptional and antigen‑presentation pathways shaping Treg identity. RNA sequencing revealed that triple knockout Tregs exhibited increased transcript diversity compared to controls. SRC‑1/NCOA1 and SRC‑2/NCOA2 were upregulated in SRC‑3 and triple knockout samples, while B2M and TRAC were strongly downregulated in triple knockouts. Chemokine transcripts were elevated in SRC‑3 and triple knockout Tregs, with triple knockouts also showing diverse cytokine upregulation. Collectively, these results demonstrate that while genome editing can enhance allogeneic compatibility, SRC‑3 is indispensable for human Treg stability and suppressive function. Effective engineering of universal Tregs must therefore balance hypoimmunogenic design with preservation of functional integrity for adoptive cell therapy.", "source_company": "Baylor College of Medicine", "source_org_type": "大学", "row_number": 533, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "Hsp90β-selective inhibitor", "company": "Grannus Therapeutics", "org_type": "公司", "target": "Hsp90β", "modality": "inhibitor", "importance_level": "中", "total_score": 53.5, "institution_score": 45, "track_score": 75, "milestone_score": 40, "field_heat_score": 65, "bonus_score": 3, "brief_reason": "药物为Hsp90β选择性抑制剂，与PARPi联用在HR熟练型卵巢癌中发挥合成致死作用，机制新颖且解决pan-Hsp90毒性问题。Grannus为早期preclinical阶段小公司，非头部机构但专注热门伴侣蛋白靶点，数据限于机制、安全和疗效研究，总潜力中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4908", "id": "TVXM_5wBX1NQZOEH-LK6", "source_drug_name": "PARP inhibitor", "title": "Synthetic lethality of Hsp90beta-selective inhibition with PARPi in homologous recombination repair proficient ovarian cancer", "abstract_text": "A significant unmet need exists for cancer patients who are ineligible for PARP inhibitor (PARPi) therapy due to their genetic makeup and/or acquired PARPi resistance. Synthetic lethality occurs when PARP inhibition is combined with an agent that disrupts the DNA double-strand breakage (DSB) repair mechanisms, causing apoptosis and cell death. Inhibition of the Heat Shock Protein 90 (Hsp90) represents an ideal candidate to disrupt DSB repair and induce synthetic lethality with PARP inhibitors, as multiple Hsp90 client proteins are involved in the DSB repair pathways including homologous recombination (HR) repair pathway. Unfortunately, no Hsp90 inhibitor is FDA approved for use due to dose-limiting and on-target toxicities. Hsp90 exists as four isoforms in the cell, Hsp90α, Hsp90β, Grp94 and Trap-1. The cytosolic isoforms Hsp90α and Hsp90β significantly contribute to cancer growth and progression. Interestingly, inhibition of Hsp90α by non-selective (pan-Hsp90) inhibitors can cause cardiac and ocular toxicities. Additionally, inhibitor binding to the inducible isoform, Hsp90α, can also contribute to dosing-challenges associated with previously evaluated pan-Hsp90 inhibitors. Therefore, Hsp90β-selective inhibition has been proposed as safer alternative to pan-Hsp90 inhibition for cancer treatment. This presentation will contain results from mechanistic, efficacy and safety studies of the orally bioavailable and efficacious Hsp90beta-selective inhibitor in combination with a PARP inhibitor.", "source_company": "Grannus Therapeutics", "source_org_type": "公司", "row_number": 536, "target_meta": "HSP90AB1", "MOA_meta": "抑制剂"}, {"drug_name": "CAR-T cell therapy", "company": "Sanford Burnham Prebys Institute", "org_type": "研究机构", "target": "未披露", "modality": "CAR", "importance_level": "中", "total_score": 53.5, "institution_score": 35, "track_score": 85, "milestone_score": 45, "field_heat_score": 75, "bonus_score": 0, "brief_reason": "该研究针对B-ALL中CAR-T细胞治疗复发机制，采用单细胞RNA-seq揭示免疫轴失调，但未披露具体新型CAR-T药物靶点或候选分子。机构为研究机构得分较低，CAR-T赛道仍具较高热度，但摘要为机制探索而非明确药物开发里程碑。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9395", "id": "yFXM_5wBX1NQZOEH-LK6", "source_drug_name": "CAR-T cell therapy", "title": "Single-cell profiling reveals immune circuit disruption preceding CAR-T relapse in B-ALL", "abstract_text": "Chimeric antigen receptor T (CAR-T) cell therapy has transformed treatment outcomes for B-cell acute lymphoblastic leukemia (B-ALL), yet disease relapse remains a major clinical challenge. To elucidate mechanisms underlying relapse, we analyzed longitudinal single-cell RNA-seq profiles from peripheral blood mononuclear cells (PBMCs) of five B-ALL patients treated with CAR-T cells. Within total T cells, MHCII⁺ CD8⁺T cells were markedly reduced at relapse, whereas naive-like CD8⁺ T cells were enriched. Trajectory reconstruction revealed that antigen-processing and antigen-presentation pathways are critical for the transition from naive-like to MHCII⁺ CD8⁺ T cells. In relapsed patients, MHCII⁺ CD8⁺ T cells exhibited impaired progression along this trajectory and remained transcriptionally similar to the naive-like state. Within the monocyte lineage, antigen-presenting monocytes in relapsed patients skewed toward a non-classical phenotype, characterized by enhanced chemotaxis, taxis, and oxidative phosphorylation, whereas a patient who maintained remission to day 360 displayed antigen-processing, antigen-presentation, and type I interferon activation signatures. Analysis of B-ALL cells revealed that relapsed leukemic cells exhibit increased stemness, “don’t-eat-me” signaling, and immaturity scores, along with reduced mature B-cell differentiation signatures. Together, our multi-patient single-cell analysis reveals a coordinated dysregulation of monocytes, CD8⁺ T-cell antigen presentation, and intrinsic leukemic cell states during CAR-T relapse, highlighting a potential B-ALL-monocyte-T-cell axis that may drive immune evasion and inform strategies to prevent or treat CAR-T failure.", "source_company": "Sanford Burnham Prebys Institute", "source_org_type": "研究机构", "row_number": 614, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "humanized OKT3", "company": "Vector Laboratories, Inc.", "org_type": "公司", "target": "CD3", "modality": "bispecific antibody", "importance_level": "中", "total_score": 53.5, "institution_score": 45, "track_score": 85, "milestone_score": 35, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "humanized OKT3为经典anti-CD3抗体臂，与trastuzumab构建双抗用于参考面板比较；Vector Laboratories旗下Absolute Antibody为抗体工程服务型公司，非头部药企，preclinical工具性研究阶段无临床里程碑。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5511", "id": "VZ7ECZ0BZznHJdntvNYd", "source_drug_name": "humanized OKT3", "title": "Comparing potential bispecific formats comprising of trastuzumab and a humanized OKT3", "abstract_text": "Purpose: This abstract showcases how Absolute Antibody (a Vector Laboratories company) generate bi-specific antibodies based on existing monoclonal antibody therapeutics molecules, compare the constructs and feasibility in order to produce “well-behaved multi-specifics”.\nExperimental Procedures: Our recombinant platform converts any antibody into customizable multispecific formats with defined Fc mutations, enabling precise control of effector function. Using trastuzumab and a humanized OKT3 variant as binding arms, we generated and expressed a panel of bispecific constructs, purified them to high quality, and compared their expression profiles, monomer content, and binding. These variants now serve as a reference set for ongoing functional and biophysical characterization studies.\nConclusions: Recent reports list 79 multi-specific antibodies in the clinic, while Absolute Antibody (a Vector Laboratories company) has produced more than 180 engineered formats. In this study, we built and analyzed 17 bispecific designs, revealing that Fc-containing architectures, scFv placement, and interface engineering strongly affect expression and stability. This reference panel highlights how design choices shape bispecific performance and is available for collaborative research.", "source_company": "Vector Laboratories, Inc.", "source_org_type": "公司", "row_number": 620, "target_meta": "CD3", "MOA_meta": "双特异性抗体"}, {"drug_name": "CLDN4-targeted peptide", "company": "Stanford University", "org_type": "大学", "target": "CLDN4", "modality": "other", "importance_level": "中", "total_score": 53.5, "institution_score": 35, "track_score": 75, "milestone_score": 55, "field_heat_score": 70, "bonus_score": 2, "brief_reason": "针对CLDN4的放射性肽用于PDAC的诊断与治疗一体化（theragnostic），靶点在胰腺癌中显著高表达且具表面可及性。斯坦福大学学术机构得分较低，但CLDN4+放射性肽成像在胰腺癌领域有较高未满足需求，preclinical阶段显示良好亲和力、稳定性及特异性肿瘤摄取。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8593", "id": "TlXM_5wBX1NQZOEH-LO6", "source_drug_name": "CLDN4-targeted peptide", "title": "Advancing pancreatic cancer theragnostic through claudin-4-selective radiolabeled peptides: Design, optimization, and preclinical validation", "abstract_text": "Accurate cancer imaging is critical for early diagnosis, guiding therapy, and assessing clinical outcomes. Yet pancreatic ductal adenocarcinoma (PDAC) poses major imaging obstacles, mainly due to its complex microenvironment, extensive stromal composition, and rapid disease progression. Claudin-4 (CLDN4), a tight junction protein, is significantly overexpressed in PDAC, making it a promising diagnostic and therapeutic target. Our spatial transcriptomic and proteomic analyses confirmed a 16-fold increase in CLDN4 expression in PDAC compared with normal pancreas. This significant finding supports its accessibility on tumor cell surfaces and suitability for molecular imaging approaches such as positron emission tomography (PET).Methods:We designed selective CLDN4-targeted peptides using solid-phase peptide synthesis, followed by rational optimization through D-amino-acid substitutions to enhance metabolic stability and dimerization strategies to improve affinity and tumor retention. The peptide structures were conjugated to a DOTA chelator through pegylated linkers of varying lengths and evaluated for serum stability. Binding affinity was measured using biolayer interferometry (BLI). Peptides were radiolabeled with ⁶⁸Ga and ⁶⁴Cu and tested in subcutaneous and transgenic PDAC-KPTC mouse models using dynamic PET/CT imaging.Results:The synthesized peptides showed good binding affinity for CLDN4 and were successfully radiolabeled with ⁶⁸Ga and ⁶⁴Cu. Serum stability studies revealed that tracers with longer PEG linkers exhibited superior stability after 4 hours of incubation. We found a similar observation with D-amino-acid-modified sequences, which showed better stability than the parent peptide. For preclinical testing, we observed that tumor uptake of the tracers gradually increased during the first hour of the dynamic scan, surpassing 10% ID/g at 40 minutes post-injection. This uptake correlated with TdTomato fluorescence, which marks cells expressing CLDN-4 in our genetically engineered model. The in-vitro imaging in a negative control subsequent model confirms the specificity of our tracers to tumors expressing claudin4. Further studies are ongoing to evaluate preclinical imaging of dimeric peptides and D-amino acid-modified sequences. This peptide-based theragnostic strategy has strong potential to improve early detection and guide targeted therapy in PDAC.", "source_company": "Stanford University", "source_org_type": "大学", "row_number": 706, "target_meta": "CLDN4", "MOA_meta": "其他"}, {"drug_name": "novel next-generation VLPs engineered to incorporate cell-adjuvanted innate ligands and present tumor-neoantigens", "company": "University of Bern", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "中", "total_score": 53.5, "institution_score": 35, "track_score": 75, "milestone_score": 55, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "该VLPs疫苗通过负载肿瘤新抗原和先天免疫佐剂激活γδ T细胞的先天与适应性抗肿瘤作用，机制新颖但靶点未明确披露。机构为大学得分较低，但个性化癌症疫苗+γδ T细胞方向在免疫治疗领域热度较高，前临床数据较扎实且显示显著生存改善。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3646", "id": "XFXM_5wBX1NQZOEH-LO6", "source_drug_name": "novel next-generation VLPs engineered to incorporate cell-adjuvanted innate ligands and present tumor-neoantigens", "title": "Preclinical potential of γδ T cells in novel virus-like particle vaccines for triple-negative breast cancer", "abstract_text": "Triple-negative breast cancer (TNBC) is an aggressive subtype with limited treatment options, high recurrence rates and poor outcomes. The conventional treatment among the standard of care strategies fail to elicit a long-term benefit for these patients. Personalized cancer vaccines using virus-like particles (VLPs), represent a promising strategy with the potential to induce durable immune responses. Recent research has highlighted the innate and adaptive properties of γδ T cells, underscoring their potential in cancer immunotherapy. However, how VLPs interact with γδ T cells, and their clinical efficacy to enhance their antitumor activity remains poorly understood and requires further investigation. We designed and developed novel next-generation VLPs engineered to incorporate cell-adjuvanted innate ligands and present tumor-neoantigens on their surface from a preclinical model of TNBC. We validated them by Cryo-EM and biochemical assays. We evaluated the interaction of VLPs with γδ T cells in wildtype and transgenic mice by transmission imaging techniques. Tumor in vivo experimentation was carried out in the 4T1 TNBC model. We compared three subcutaneous (s.c.) administration routes: systemic, targeting tumor-draining lymph nodes (tdLNs), and targeting non-tdLNs. Survival was assessed under different dosing and immune checkpoint inhibitor co-treatment. CD4, CD8, and γδ T cells were depleted to determine their contributions. We performed immunohistochemistry, flow cytometry, and RNA-seq analysis to evaluate the immune response. Our results show that γδ T cells efficiently engulfed VLPs in wild-type mice while this interaction is hindered in transgenic mice lacking key components of innate immune sensing pathways. Our novel VLPs expanded γδ T cells in tdLNs, promoting antitumor subsets and phenotypes. Subtype analysis revealed distinct activation profiles of γδ T cells subsets Vγ-1 and Vγ-4. Evaluation of tdLNs and tumors revealed early expansion of γδ T cells, highlighting innate properties. Depletion of γδ T cells abolished antitumor efficacy of the immunotherapy, suggesting adaptive properties. Furthermore, our personalized vaccine enhanced tumor infiltration of CD4, CD8 and γδ T cells, increased cytotoxic markers, reduced recurrence and metastasis, and improved survival despite low tumor mutational burden. Our findings reveal novel innate and adaptive properties of γδ T cells in response to our next-generation VLPs loaded with diverse innate immune stimuli and presenting tumor-neoantigens from 4T1 cells. These findings have the potential to reshape the field of cancer vaccines by harnessing γδ T cells as key players in anti-tumor immunity.\n(AI tools were used only to improve the clarity of the text in this abstract. All content was reviewed and verified by the authors.)", "source_company": "University of Bern", "source_org_type": "大学", "row_number": 712, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "gadolinium-based nanocomposite", "company": "Tianjin Medical Univ. Cancer Inst. & Hospital", "org_type": "医院", "target": "未披露", "modality": "other", "importance_level": "中", "total_score": 53.5, "institution_score": 35, "track_score": 75, "milestone_score": 55, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "GdB为钆基纳米复合物，具有放射增敏、cGAS-STING介导的免疫激活及MRI显像功能，靶点未明确披露。机构为国内三甲肿瘤医院得分一般，赛道结合诊断治疗一体化与免疫-放疗协同具较高热度，处于较强preclinical阶段但非临床里程碑。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6393", "id": "glXM_5wBX1NQZOEH-LO6", "source_drug_name": "gadolinium-based nanocomposite", "title": "Gadolinium-based nanocomposite as a theranostic agent for triple-negative breast cancer: Synergistic radiosensitization, immune modulation, and image-guided therapy", "abstract_text": "Purpose: Triple-negative breast cancer (TNBC) is an aggressive malignancy with limited therapeutic options and frequent radiotherapy (RT) resistance. This study developed a novel gadolinium-based nanocomposite (GdB) with dual functions—radiosensitization and immune modulation—to establish a diagnostic-therapeutic integrated approach for precision RT in TNBC.\nMethods: GdB nanoparticles were characterized structurally (TEM, XRD, EELS) and functionally (peroxidase-like activity). Cytotoxicity and radiosensitization were assessed in vitro using CCK-8, colony formation assays, apoptosis (flow cytometry, JC-1 staining), ROS generation, and DNA damage (γ-H2AX immunofluorescence and Western blot). Biocompatibility was evaluated in vivo using blood biochemistry, histopathology, and fluorescence imaging. The mechanism of immune activation was verified by measuring immunogenic cell death markers (CRT, ATP, HMGB1 release) and identifying activated pathways through transcriptomic analysis and qPCR. Immune responses were tracked in vitro (co-culture, cytokine secretion) and in vivo. Immune cell infiltration, cytokine levels (ELISA), and the immune landscape of primary and distant tumors were comprehensively analyzed using flow cytometry and single-cell RNA sequencing.\nResults: GdB formed uniform spherical crystalline nanoparticles exhibiting excellent peroxidase-like activity. Mechanistically, GdB significantly enhanced radiosensitivity by promoting DNA damage and apoptosis. GdB induces ICD and activates the cGAS-STING pathway, leading to Type I interferon production, providing a robust basis for immune enhancement. GdB demonstrated excellent biocompatibility in vivo at experimental doses. Functionally, GdB served as an MRI contrast agent, enhancing tumor contrast for precise GTV delineation and facilitating real-time monitoring of tumor response to RT. Therapeutically, the combination of GdB with RT markedly inhibited tumor growth by reprogramming the tumor microenvironment from an immunosuppressive \"cold\" state to an immune-activated \"hot\" state. This conversion was marked by increased infiltration of key effector immune cells and elevated levels of anti-tumor cytokines. Crucially, the combination treatment generated a systemic anti-tumor immune response, resulting in the inhibition of distant metastases.\nConclusion: GdB is a highly effective theranostic platform for precision radiotherapy in TNBC, as its dual functions of radiosensitization and cGAS-STING pathway-mediated immune modulation substantially enhance RT efficacy and systemic anti-tumor response. Furthermore, its function as an MRI contrast agent integrates precise diagnosis with enhanced therapeutic outcomes, supporting its strong potential for clinical translation in image-guided radiotherapy.", "source_company": "Tianjin Medical Univ. Cancer Inst. & Hospital", "source_org_type": "医院", "row_number": 737, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "TM4SF1-targeting ADC", "company": "Yonsei New Il Han Institute for Integrative Cancer Research", "org_type": "研究机构", "target": "TM4SF1", "modality": "ADC", "importance_level": "中", "total_score": 53.5, "institution_score": 35, "track_score": 85, "milestone_score": 45, "field_heat_score": 70, "bonus_score": 2, "brief_reason": "TM4SF1是一个在多种实体瘤（尤其是KRAS突变型）中高表达、正常组织低表达的靶点，适合ADC开发，具有双重打击肿瘤细胞和血管潜力的新兴靶点。机构为大学附属研究机构而非商业公司，得分较低；赛道为热门ADC+新兴靶点，in vitro数据较扎实但仍处preclinical早期，综合热度中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4356", "id": "mVXM_5wBX1NQZOEH-LO6", "source_drug_name": "TM4SF1-targeting ADC", "title": "TM4SF1 as a promising ADC target for KRAS-mutated cancers", "abstract_text": "Transmembrane 4 L six family 1 (TM4SF1) is a protein with four transmembrane domains belonging to the transmembrane 4 L six family members. TM4SF1 interacts with tetraspanins, integrins, and various receptor tyrosine kinases. TM4SF1 promotes cancer cell migration and invasion and is overexpressed in many epithelial-derived malignancies, including prostate, breast, pancreatic, lung, colon, and gastric cancers, while found at low concentrations in normal human tissues like endothelium, skin, lung, and germ cells. In this study, we evaluated TM4SF1 as an ADC (antibody-drug conjugate) target and investigated its connection with KRAS-mutated cancer.To evaluate the potential of TM4SF1 as an ADC target, we employed both in silico analysis and in vitro assays. In silico analysis included data from TCGA/GTEx, single-cell RNA sequencing, and DEPMAP. In vitro assays comprised flow cytometry, internalization assays using IncuCyte, colony formation assays after gene knockdown, and cell viability assays using an ADC which was conjugated by ADC kit (CellMosaic, Inc., MA, USA).The key findings suggest that TM4SF1 is highly expressed in various solid tumors, particularly in KRAS-mutated tumors, indicating it is a promising ADC target. In silico analysis results revealed that TM4SF1 expression was significantly higher in lung cancer, pancreatic cancer, colorectal cancer, and bile duct cancer tumors compared to normal tissues; specifically, following our in-house scRNA sequencing data, expression was increased in EGFR wild-type and post-TKI treated lung tumors, and viability decreased upon gene knockout in many types of solid tumor. In vitro analysis confirmed TM4SF1 expression levels suitable for ADC targeting in 86% to 100% of various cancer cell lines (lung, pancreatic, colorectal, liver, gastric, etc.). Functional analysis demonstrated that TM4SF1 was internalized efficiently (comparable to or greater than the positive control CD71), and lung cancer cell line with high expression and KRAS mutation responded more sensitively to TM4SF1-targeting ADCs compare to low expression and without KRAS mutation or normal cell line. Our findings demonstrate that TM4SF1 is highly expressed in various solid tumors, particularly in specific genetic subsets such as those with KRAS mutated tumors. The observed high expression levels, efficient internalization kinetics (comparable to the positive control CD71), and robust in vitro efficacy of TM4SF1-targeting ADCs strongly suggest that TM4SF1 is a promising therapeutic target. These results provide a strong rationale for the clinical development of TM4SF1-targeting ADCs as a novel precision oncology treatment strategy across multiple cancer types.", "source_company": "Yonsei New Il Han Institute for Integrative Cancer Research", "source_org_type": "研究机构", "row_number": 751, "target_meta": "TM4SF1", "MOA_meta": "抗体偶联药物"}, {"drug_name": "ATM inhibitor", "company": "UC Davis Medical Center", "org_type": "医院", "target": "ATM", "modality": "inhibitor", "importance_level": "中", "total_score": 53.5, "institution_score": 35, "track_score": 75, "milestone_score": 55, "field_heat_score": 65, "bonus_score": 2, "brief_reason": "临床阶段ATM抑制剂针对PARPi耐药的前列腺癌中DTP/DTEP细胞显示预防进展和再增敏作用，机制针对DNA损伤响应通路。医院机构得分较低，但ATM+PARPi组合在耐药背景下具有一定转化潜力，整体中等重要性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4897", "id": "tlXM_5wBX1NQZOEH-LO6", "source_drug_name": "PARP inhibitor", "title": "Targeting PARPi drug tolerant persistence and progression on treatment with clinical stage ATM inhibitors in advanced prostate cancer", "abstract_text": "Background: PARP inhibitors (PARPi) have improved prostate cancer management, but progression is inevitable. Drug tolerant persistence (DTP) is characterized by tumor cells which survive treatment and drive failure through transient acquisition of insensitivity. Cycling DTP cells may adapt and expand, giving rise to drug tolerant expanded persister (DTEP) populations which are thought to model progression on treatment. Emerging evidence supports a critical role for DTP in promoting PARPi progression. Identifying and targeting DTP and DTEP vulnerabilities may provide therapeutic strategies to combat disease progression.\nMethods: Viability assays, western blots, and additional assays defined treatment response in PARPi-sensitive C4-2B metastatic castration-resistant prostate cancer cells and C4-2B abiraterone-resistant derivative AbiR cells. DTP and DTEP models were developed through prolonged PARPi exposure. NGS profiled DTP cells. Clinical stage ATM inhibitors were tested for their effects on both DTP and DTEP populations.\nResults: Response to PARP inhibition is heterogeneous, characterized by cell death and emergence of a largely cytostatic, persistent population. C4-2B and AbiR cells exposed to clinically relevant PARPi dosing for 9 days followed by drug holiday regain normal, parental cell morphology and become re-sensitized to treatment in line with acquisition of a DTP phenotype. DTP cells display differential sensitivity to other classes of drugs compared to parental cells. DTP cells may be broadly stratified into two classes; 1) a minority which cycle and 2) those which don’t. Prolonged PARPi treatment is observed to result in drug tolerant expanded persisters (DTEP) derived from cycling-DTP cells. DTP and DTEP cells display increased phospho-ATM levels suggesting constitutive DNA damage response activation. Utilization of clinical stage ATM inhibitors both prevent DTP progression into DTEPs and resensitize DTEPs to PARP inhibition.\nConclusions: Our data suggest that drug tolerant persistence may mediate survival of tumor cells which drive progression on treatment. ATM inhibition may be used to prolong time to progression or to treat progressive disease. Future studies will focus on translating these strategies.", "source_company": "UC Davis Medical Center", "source_org_type": "医院", "row_number": 775, "target_meta": "ATM", "MOA_meta": "抑制剂"}, {"drug_name": "RD-23", "company": "University of Minnesota", "org_type": "大学", "target": "RET", "modality": "PROTAC", "importance_level": "中", "total_score": 53.5, "institution_score": 35, "track_score": 85, "milestone_score": 45, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "RD-23为基于selpercatinib的RET PROTAC，针对ASCL1调控的RET在NEPC中的作用。大学机构得分较低，但PROTAC赛道+RET靶点在NEPC中的新机制探索具有一定热度和潜力。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4400", "id": "3FXM_5wBX1NQZOEH-LO6", "source_drug_name": "RD-23", "title": "ASCL1-mediated transcriptional regulation of RET in neuroendocrine prostate cancer", "abstract_text": "Resistance to second-generation anti-androgen therapies can cause neuroendocrine prostate cancer (NEPC), an aggressive disease variant, in castration-resistant prostate cancer (CRPC) patients. With low survival outcomes and limited therapies, it is imperative to study the molecular basis of NEPC. We show that the receptor tyrosine kinase RET has elevated activity in aggressive variant prostate cancer cell lines. We also show that RET kinase is crucial for the growth and survival of NEPC cells. We aim to unravel the mechanism of RET activation in NEPC to develop novel approaches to target RET and identify additional drug targets. NEPC can be categorized into two subtypes based on the expression of ASCL1 or NEUROD1, two pro-neuronal transcription factors. We show that RET gene expression strongly correlates to ASCL1 gene expression, but not NEUROD1 gene expression in NEPC patient samples. This data is corroborated by single cell-RNA-sequencing data in NEPC patient samples. Informatics modeling of whole transcriptome sequencing data from patient samples shows that RET and ASCL1 have substantially similar gene network signatures in NEPC, implying that these genes share a gene ecosystem in NEPC. To investigate the relationship between RET and ASCL1, we analyzed publicly available ChIP-sequencing data from LuCaP NEPC PDX models and small cell lung cancer (SCLC) cell lines. NEPC and SCLC are known to have similarities, including disease aggressiveness, expression of neuroendocrine markers, and the presence of ASCL1-positive and NEUROD1-positive subtypes. Our analysis showed that ASCL1 directly regulates RET by binding to RET promoter regions. Hence, we note a similar relationship between RET and ASCL1 in SCLC where ASCL1 regulates RET expression. Using knockdown models, we show that the RET-ASCL1 axis is unidirectional with RET having no impact on ASCL1 expression. To drug this pathway, we aim to focus on cell surface targets such as RET. RET inhibitors are approved for non-small cell lung cancers or thyroid cancers with RET fusions, however, they may induce resistance via mutations. Additionally, they may be less effective in tumors with wild-type RET expression, which is typically seen in NEPC. PROTACs can bypass these drawbacks by degrading the entire protein instead of enzymatically inhibiting it, thus overcoming drug resistance. Additionally, PROTACs have a catalytic mechanism that can cause degradation of several target molecules with one PROTAC molecule, leading to longer elimination of target protein with lower doses. We are using RD-23, a published RET PROTAC based on the RET inhibitor selpercatinib, to investigate its effects on NEPC and SCLC cells. While further studies are needed to stratify patients and develop novel pharmacological interventions, these results highlight the crucial role of ASCL1 in mediating RET signaling in NEPC and SCLC.", "source_company": "University of Minnesota", "source_org_type": "大学", "row_number": 805, "target_meta": "RET", "MOA_meta": "PROTAC"}, {"drug_name": "next-generation caPCNA inhibitors", "company": "Beckman Research Institute of The City of Hope", "org_type": "研究机构", "target": "caPCNA", "modality": "inhibitor", "importance_level": "中", "total_score": 53.5, "institution_score": 35, "track_score": 75, "milestone_score": 55, "field_heat_score": 60, "bonus_score": 2, "brief_reason": "靶向癌相关增殖细胞核抗原caPCNA的小分子抑制剂，通过干扰DNA复制与修复展现抗肿瘤潜力。研究机构背景+preclinical组合筛选阶段导致机构分较低，但新型caPCNA抑制剂优化及广泛协同潜力使赛道分较高，总分处于中等水平。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4032", "id": "7FXM_5wBX1NQZOEH-LO6", "source_drug_name": "next-generation caPCNA inhibitors", "title": "Antitumor synergy of AOH1996 and next-generation caPCNA Inhibitors in combination with targeted and chemotherapeutic agents", "abstract_text": "Background: AOH1996 is a small molecule that selectively targets the cancer-associated isoform of proliferating cell nuclear antigen (caPCNA), disrupting DNA replication and repair, and promoting DNA strand breaks through inhibition of effective resolution of transcription-replication conflicts. Building on its promising preclinical efficacy, we are also developing and testing next-generation caPCNA inhibitors with improved potency and druglikeness. We have developed two new inhibitors that exhibit up to 10-fold higher cellular potency relative to the parent compound, and an inhibitor with similar potency as the parent compound but 2.4-fold more soluble. Given PCNA’s diverse role in processes that cancer cells depend upon for survival, e.g., coordinating DNA synthesis, damage tolerance, cell cycle control, chromatin assembly, and stress response signaling, it is hard to predict what other anticancer drugs would combine productively with AOH1996 and next-generation inhibitors. To that end, we screened a panel of 179 anticancer drugs with AOH1996 and three next-generation inhibitors to identify potential combinations that exhibit synergy.\nMethods: A systematic combination drug screen was performed using AOH1996 and next-generation inhibitors and a drug panel of 179 different anticancer drugs. \n Synergy evaluation: We performed initial screens using the human neuroblastoma cell line SK-N-AS. We assessed the synergy of the combinations using the Chou-Talalay method for drug combination analysis. For favorable drug combinations, we tested additional cell lines including cancer cell types where the drug identified would be used clinically in a treatment regimen. Mechanistic studies: We analyzed cell cycle effects and apoptosis by flow cytometry. We also assessed DNA damage and checkpoint activation by using immunoblotting and immunofluorescence to measure γH2AX, cleaved PARP, and phospho-Chk1.   Results: Both AOH1996 and its next-generation analogs demonstrated synergy with some DNA-damaging and repair inhibiting agents such as cisplatin. Tyrosine kinase inhibitors (TKIs) in particular EGFR TKIs synergized well with AOH1996 and next-generation inhibitors. Inhibitors of the mitochondrial apoptosis pathway (e.g., venetoclax) also synergized as well.\nConclusions: AOH1996 and its next-generation analogs exhibit potent synergistic activity with targeted therapies and DNA repair inhibitors, supporting PCNA inhibition as a promising strategy to enhance therapeutic efficacy and overcome resistance. These findings provide a preclinical rationale for clinical development of AOH1996 combination regimens, as well as continued optimization of caPCNA-targeting analogs with superior potency and tolerability.", "source_company": "Beckman Research Institute of The City of Hope", "source_org_type": "研究机构", "row_number": 817, "target_meta": "PCNA", "MOA_meta": "抑制剂"}, {"drug_name": "DN146", "company": "University of Illinois Chicago College of Medicine", "org_type": "大学", "target": "未披露", "modality": "oncolytic virus", "importance_level": "中", "total_score": 53.5, "institution_score": 35, "track_score": 75, "milestone_score": 55, "field_heat_score": 70, "bonus_score": 4, "brief_reason": "DN146为优化的溶瘤HSV，通过重塑γ1 34.5基因强激活STING/RIG-I并携带高亲和SIRPα阻断CD47，展现优异的免疫刺激和双侧肿瘤清除能力。大学机构得分较低，但溶瘤病毒+新型免疫检查点改造赛道热度较高，前临床数据较强，综合为中等重要性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5172", "id": "7VXM_5wBX1NQZOEH-LO6", "source_drug_name": "DN146", "title": "Modulating the tumor microenvironmentwith an engineered oncolytic herpesvirus facilitates potent antitumor response", "abstract_text": "Oncolytic viruses (OV) are a promising approach to cancer treatment, whereby attenuated viruses selectively infect and kill tumors, while sparing healthy cells. Tumor antigens and cytokines released from infected cells prime and activate the immune system to generate durable antitumor responses. This inflames the tumor microenvironment and may complement immune checkpoint inhibitor (ICI) therapy. However, this synergy is yet to be demonstrated: in a randomized, double blind, phase III trial, the HSV based talimogene laherparepvec (TVEC) in combination with anti-PD1 ICI therapy failed to improve both progression free survival and overall survival relative to anti-PD1 therapy alone. This may be attributable to viral factors that promote tumor selective replication in part by suppressing antitumor immune elements. Consequently, there is an unmet need for OVs that overcome the limitations of current therapies. We previously developed a novel oncolytic HSV, DN146, optimized for maximum immune stimulation without compromising tumor selective replication. Re-engineering of the γ1 34.5 gene in DN146 permits efficient viral replication and tumor cell killing, while robustly activating STING and RIG-I. In vivo, DN146 exhibits strong immune stimulation and dendritic cell maturation, and robust clearance of metastatic lesions as compared to clinical analogues in a mouse model of triple negative breast cancer. We armed DN146 with an engineered high affinity SIRPα to further potentiate its antitumor effects by blocking the SIRPα-CD47 immune checkpoint. Antagonists of this checkpoint improve macrophage phagocytosis and T-cell recruitment to the TME. Further, CD47 blockade can improve cross presentation of tumor antigens to CD8+ T-cells. Together, these effects should cooperate with STING activation from DN146 to broadly reprogram the tumor microenvironment. When tested in a bilateral, murine colorectal cancer model, this virus achieves clearance of both locally injected and distal un-injected tumors, indicating strong local and systemic antitumor effects.", "source_company": "University of Illinois Chicago College of Medicine", "source_org_type": "大学", "row_number": 818, "target_meta": "not available", "MOA_meta": "溶瘤病毒"}, {"drug_name": "MM017", "company": "UT Southwestern Medical Center", "org_type": "医院", "target": "NVL", "modality": "inhibitor", "importance_level": "中", "total_score": 53.5, "institution_score": 45, "track_score": 65, "milestone_score": 55, "field_heat_score": 60, "bonus_score": 2, "brief_reason": "MM017为新型苯并硫氮卓类小分子抑制剂，靶向核内NVL（AAA+转位酶），阻断60S核糖体大亚单位组装从而抑制结直肠癌细胞增殖。机构为学术医疗中心而非头部药企得分为中等偏低，靶点NVL为核糖体生物合成新靶点具一定创新性但非热门，处于preclinical早期阶段但有SAR优化及体内前药评估，综合热度中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6562", "id": "FVXM_5wBX1NQZOEH-LS6", "source_drug_name": "MM017", "title": "The NVL inhibitor benzothiazepinone targets colorectal cancer by blocking ribosome biogenesis", "abstract_text": "The identification of new cancer-relevant protein targets is a major bottleneck in the discovery of small molecule therapies for the treatment of cancer. To meet this challenge, our team developed a platform that combines cell-based, high throughput phenotypic screens with forward genetics to identify new cancer targets and accompanying small molecule leads. By combining this approach with biochemical reconstitution and structural biology, we identified MM017 (benzothiazepinone scaffold) as a novel small molecule with anti-proliferative activity in colorectal cancer cells and its target nuclear valosin-containing protein-like (NVL), a hexameric AAA+ translocase required for large ribosomal subunit (60S) assembly. Simultaneously, an advanced medicinal chemistry campaign was launched to establish the SAR and to evaluate how continual modification balances the chemical-physical properties of candidate small molecules. Compounds that meet minimal criteria for in vitro ADME properties are progressed through the funnel and further evaluated through preclinical models to assess pharmacokinetics, toxicity, and efficacy.", "source_company": "UT Southwestern Medical Center", "source_org_type": "医院", "row_number": 846, "target_meta": "NVL", "MOA_meta": "抑制剂"}, {"drug_name": "PD-1 blockade", "company": "Columbia University", "org_type": "大学", "target": "PD-1", "modality": "inhibitor", "importance_level": "中", "total_score": 53.5, "institution_score": 35, "track_score": 85, "milestone_score": 45, "field_heat_score": 75, "bonus_score": 3, "brief_reason": "利用工程化EcN细菌表达CXCL13增强肿瘤特异性体液免疫并协同PD-1 blockade提升膀胱癌免疫治疗效果。大学机构得分较低，但PD-1+新型细菌递送增强抗体应答的组合策略在热门免疫治疗赛道具有一定创新性和潜力。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/738", "id": "cJ7ECZ0BZznHJdntvNYd", "source_drug_name": "PD-1 blockade", "title": "Tumor-specific antibodies elicited by engineered bacteria promote bladder cancer immunotherapy", "abstract_text": "The intratumoral microbiome has recently emerged as a new hallmark of cancer, with implications for response or resistance to therapy. While bacteria can either promote or inhibit cancer growth, intratumoral bacteria can also be engineered using synthetic biology to remodel the tumor microenvironment. Here, we engineered the probiotic bacterium E. coli Nissle 1917 (EcN) to express the human chemokine CXCL13, a critical component of germinal center (GC) formation. The GC reaction is a fundamental aspect of adaptive immunity by which antibody affinity develops in secondary lymphoid organs for defense against pathogens. Using orthotopic models of bladder cancer, engineered CXCL13-expressing EcN colonized bladder tumors and elicited GC responses in bladder tumor-draining lymph nodes after intravesical delivery. Furthermore, when combined with PD-1 blockade, engineered EcN amplified the antitumor antibody response and promoted long-term survival and protective immunity upon tumor rechallenge. Thus, we demonstrate that synthetically engineered CXCL13-expressing EcN can enhance the efficacy of PD-1 checkpoint blockade immunotherapy by amplifying tumor-specific humoral immunity.", "source_company": "Columbia University", "source_org_type": "大学", "row_number": 884, "target_meta": "PD1", "MOA_meta": "抑制剂"}, {"drug_name": "MR-2088", "company": "Moffitt Cancer Center", "org_type": "医院", "target": "ULK1/2", "modality": "inhibitor", "importance_level": "中", "total_score": 53.5, "institution_score": 35, "track_score": 75, "milestone_score": 60, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "MR-2088为选择性ULK1/2抑制剂，通过阻断自噬增强KRAS通路抑制剂在KRAS突变肿瘤中的疗效，具有清晰的体外/体内协同作用和PK支持。机构为知名癌症研究中心但非商业药企得较低分，靶点+自噬+KRAS相关赛道热度较高，但仍处preclinical阶段综合为中重要性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5035", "id": "a1XM_5wBX1NQZOEH-LS6", "source_drug_name": "MR-2088", "title": "Selective ULK1/2 inhibitors enhance KRAS pathway blockade and uncover stress-adaptive programs", "abstract_text": "KRAS is the most frequently mutated member of the RAS family in lung adenocarcinomas such as NSCLC. Although KRAS pathway inhibition can reduce tumor growth, resistance arises and thwarts its clinical potential. Prior work has suggested that the autophagy pathway is an exploitable vulnerability for mutant RAS-driven tumors. ULK1 is a central upstream regulator of the autophagy pathway, and its inhibition is a promising strategy to abrogate autophagy and improve RAS-driven tumor sensitivity to approved therapeutics. Through structure-based drug design, we generated a 7-azaindole-derived series of ULK1/2 inhibitors and characterized their structure-activity relationships. Biochemical potency was measured via ULK1/2 enzymatic assays, and intracellular target engagement was evaluated using a ULK1 NanoBRET assay. Cellular analyses were performed in KRAS mutant models using viability assays, autophagy flux measurements under starvation or treatment with MEK inhibitor. Combination studies with RAF-MEK-ERK pathway inhibitors were assessed in subcutaneous xenograft models. In order to assess the type of resistance arising from KRAS treatment, we used a combination of DNA barcode technology and transcriptomic studies to distinguish between resistance arising from clonal expansion vs adaptive, reversible survival programs consistent with drug-tolerant persister (DTP) biology. We identified potent, selective ULK1/2 inhibitors, favorable physicochemical profiles, and strong cellular target engagement. The lead analog, MR-2088, inhibited stimuli-induced autophagic flux and displayed pharmacokinetics appropriate for in vivo studies. In cells, MR-2088 enhanced the activity of MEK/ERK inhibitors and produced synergistic reductions in viability. The synergistic effect was observed in vivo. DNA barcode analysis revealed that resistance emerging after KRAS pathway inhibition was not associated with expansion of distinct clonal populations, suggesting a non-genetic adaptive mechanism. Transcriptomic profiling showed enrichment of stress-adaptive pathways, including cell-cycle remodeling, metabolic rewiring, oxidative phosphorylation, and MYC-regulated targets; patterns consistent with previously described drug-tolerant persister-like programs. This study describes a new chemotype of selective, ULK1/2 inhibitors that robustly engage the target, inhibit autophagic flux, and enhance the effectiveness of RAS pathway inhibitors. By disrupting autophagy-supported adaptive programs that arise following KRAS pathway inhibition, ULK1 blockade may enhance therapeutic responses and limit stress-induced survival states relevant to treatment tolerance. These findings support further investigation of ULK1 inhibition as a strategy to augment targeted therapy in KRAS-driven malignancies.", "source_company": "Moffitt Cancer Center", "source_org_type": "医院", "row_number": 907, "target_meta": "not available", "MOA_meta": "抑制剂"}, {"drug_name": "anti-PD-1", "company": "UT MD Anderson Cancer Center", "org_type": "医院", "target": "PD-1", "modality": "inhibitor", "importance_level": "中", "total_score": 53.5, "institution_score": 35, "track_score": 85, "milestone_score": 45, "field_heat_score": 80, "bonus_score": 0, "brief_reason": "anti-PD-1为经典免疫检查点抑制剂，靶向PD-1通路在肿瘤免疫治疗中具有高热度和成熟机制。机构为顶尖肿瘤医院而非药企，研究聚焦液体活检生物标志物开发而非药物本身新进展，导致整体重要性中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9808", "id": "fFXM_5wBX1NQZOEH-LS6", "source_drug_name": "anti-PD-1", "title": "Longitudinal liquid biopsy identifies an early predictive biomarker of immune checkpoint blockade response in head and neck squamous cell carcinoma", "abstract_text": "Immune checkpoint inhibition (ICI) has emerged as a pivotal therapy for head and neck squamous cell carcinoma (HNSCC), yet the development of predictive biomarkers to guide its clinical application has significantly lagged. Current biomarkers such as tumor mutational burden and PD-L1 fail to capture systemic immune dynamics that may better reflect host immune fitness and the coordinated immune response driving durable tumor control. We hypothesized that early treatment-induced changes in circulating immune repertoires could provide a dynamic, non-invasive readout of ICI responsiveness. Using a time-resolved, multi-omic approach in a murine HNSCC model, we characterized peripheral immune responses to anti-PD-1 across defined pre- and on-treatment timepoints. Single-cell transcriptomics and paired T/B cell receptor analyses revealed an early and robust, but transient, expansion of effector memory T and B cell repertoires in responders, preceding tumor regression. Temporal changes in effector T and B cell abundance, clonality, and gene expression strongly predicted immunotherapy response, with early on-treatment timepoints emerging as the optimal window for assessing treatment response. These dynamic immune features informed a composite transcriptional signature, Liquid Biomarker for Immuno-Oncology (LiBIO), derived from effector T and B cell programs that accurately predicts ICI response in independent human HNSCC cohorts and outperforms contemporary biomarkers such as PD-L1 combined positive score and tumor mutational burden. LiBIO further generalizes to melanoma, non-small cell lung cancer, and breast cancer without retraining, suggesting that early peripheral immune dynamics capture conserved features of effective antitumor immunity across cancer types. Collectively, these findings support the premise that antitumor immune responses initiated regionally in tumor-draining lymphatics give rise to transient, stereotyped peripheral immune responses that precede successful primary tumor control, and that peripheral immune events can serve as a foundation for liquid biomarker discovery. This innovative approach represents a paradigm shift from static, tumor-centric biomarkers to dynamic monitoring of host immunity, enabling real-time treatment adaptation during the critical early window of immune activation.", "source_company": "UT MD Anderson Cancer Center", "source_org_type": "医院", "row_number": 919, "target_meta": "PD1", "MOA_meta": "抑制剂"}, {"drug_name": "CYA", "company": "Reaction Biology Europe GmbH", "org_type": "公司", "target": "未披露", "modality": "other", "importance_level": "中", "total_score": 53.5, "institution_score": 45, "track_score": 60, "milestone_score": 55, "field_heat_score": 70, "bonus_score": 2, "brief_reason": "CYA是一种抗炎化合物，与anamorelin联用在C26模型中显示协同改善癌性恶病质体质量和脂肪保存，但靶点未明确披露。机构为CRO公司非头部药企、处于preclinical组合验证阶段、癌性恶病质领域需求高但赛道非最热门导致综合评分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9067", "id": "pFXM_5wBX1NQZOEH-LS6", "source_drug_name": "CYA", "title": "A clearer picture of cachexia: Leveraging body composition imaging in C26 tumored mice", "abstract_text": "Cancer cachexia remains a major unmet need in oncology, characterized by progressive loss of skeletal muscle and adipose tissue that negatively impacts treatment tolerance and survival. Anamorelin (AML), a ghrelin receptor agonist, is currently the only approved therapeutic for cancer cachexia; however, its clinical benefits remain modest, highlighting the need for improved preclinical models and more informative physiological endpoints. Here, we established and characterized a C26 colorectal carcinoma cachexia model using both traditional metrics and non-invasive body composition imaging performed on a Bruker MiniSpec. This platform enabled longitudinal quantification of lean and fat mass changes with high sensitivity, providing a refined assessment of cachexia progression and therapeutic response.In vitro and in vivo studies confirmed the robust cachexia-inducing phenotype of the C26 model. Consistent with published literature, AML treatment increased food intake in tumor-bearing mice but did not reduce circulating pro-inflammatory cytokines. Combination therapy, evaluated based on the mechanistic rationale that AML-mediated appetite stimulation may complement the anti-inflammatory activity of CYA, demonstrated enhanced preservation of body mass and adipose tissue compared with either monotherapy. Our findings support the utility of integrating body composition imaging with standard physiological and biochemical measures to generate a comprehensive efficacy profile. These results highlight the value of this refined platform for evaluating emerging cachexia therapeutics and suggest that multi-modal combinations such as CYA+AML may provide superior benefit over current single-agent approaches.", "source_company": "Reaction Biology Europe GmbH", "source_org_type": "公司", "row_number": 950, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "PARP inhibitor", "company": "West China Hospital, Sichuan University", "org_type": "医院", "target": "PARP", "modality": "inhibitor", "importance_level": "中", "total_score": 53.5, "institution_score": 35, "track_score": 75, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "PARP抑制剂靶向DNA损伤修复通路，在SCLC放射免疫治疗耐药模型中显示并发联合可显著改善肿瘤控制和生存，已有前瞻性临床试验（NCT06217757）正在进行。机构为国内顶级医院但非商业药企导致机构分较低，赛道为成熟但仍有潜力的PARPi+免疫+放疗组合，preclinical证据较强且有转化价值。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4636", "id": "ep7M_5wBZznHJdnt_W3O", "source_drug_name": "PARP inhibitor", "title": "Targeting DNA damage repair pathway and CCR2⁺ myeloid cell to overcome radioimmunotherapy resistance in small cell lung cancer", "abstract_text": "Background: Small cell lung cancer (SCLC) is a highly aggressive neuroendocrine carcinoma characterized by rapid progression and a high relapse rate. Although the combination of immune checkpoint inhibitors (ICIs) with radiotherapy (RT) has improved patient outcomes, acquired resistance remains inevitable. This study aims to elucidate the underlying mechanisms of radioimmunotherapy resistance and explore potential novel strategies.\nMethods: We established a murine SCLC model of acquired radioimmunotherapy resistance by subjecting tumor-bearing mice to multiple cycles of RT + ICI until resistance developed. Subsequently, longitudinal single-cell RNA sequencing (scRNA-seq) analysis of tumor specimens was performed to validate the findings. The DNA damage repair (DDR) pathway was investigated using Western Blot, ELISA, and Transwell assays. The efficacy of adding PARP inhibitor (PARPi) to RT+ICI was evaluated in vivo.\nResults: Analysis of the radioimmunotherapy-resistant murine SCLC model revealed that enhanced DDR activity, elevated CCL2 secretion, and increased of infiltration of CCR2⁺ myeloid-derived suppressor cells (MDSCs), which were further validated by longitudinal scRNA-seq. Targeting the CCL2-CCR2 axis significantly delayed tumor relapse following RT + ICI treatment. Next, in vitro, combining PARPi with RT synergistically suppressed DDR activation and inhibited CCL2-dependent MDSC migration. In vivo, concurrent administration of PARPi with RT + ICI was essential for achieving better tumor control and survival benefit compared with RT + ICI treatment, whereas delayed intervention of PARPi proved ineffective. Tumor microenvironment analysis demonstrated that the triple therapy (RT + ICI + concurrent PARPi) effectively suppressed the DDR pathway, significantly reduced CCR2⁺ MDSC infiltration, and increased effector T cell recruitment.\nConclusion: DDR-driven CCL2 secretion recruits CCR2⁺ MDSCs to mediate radioimmunotherapy resistance in SCLC. PARPi disrupts this axis through dual blockade of tumor DDR and MDSC recruitment. Our data revealed that the combination of concurrent PARPi with radio-chemo-immunotherapy as first line therapy in ES-SCLC is worth exploring and a prospective clinical trial is ongoing (NCT06217757).", "source_company": "West China Hospital, Sichuan University\nWest China Hospital", "source_org_type": "医院", "row_number": 1033, "target_meta": "PARP", "MOA_meta": "抑制剂"}, {"drug_name": "PD-1 blockade", "company": "University of California San Diego", "org_type": "大学", "target": "PD-1", "modality": "inhibitor", "importance_level": "中", "total_score": 53.5, "institution_score": 35, "track_score": 75, "milestone_score": 55, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "PD-1 blockade为经典免疫检查点抑制剂，联合SLN来源的过继细胞治疗在HPV阴性头颈癌模型中显示增强疗效。大学机构得分较低，但PD-1赛道热度高、组合策略有一定创新，整体处于中等重要性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9359", "id": "x57M_5wBZznHJdnt_W3O", "source_drug_name": "PD-1 blockade", "title": "Sentinel lymph node-derived CD45⁺ cells combined with low-dose radiotherapy and PD-1 blockade as a next-generation adoptive cell therapy in head and neck cancer", "abstract_text": "Purpose: Head and neck squamous cell carcinoma (HNSCC) is the seventh most common cancer globally, representing roughly 6% of all malignancies. Each year it accounts for an estimated 660,000 new diagnoses and over 325,000 deaths, with incidence projected to rise by nearly 30% by 2030. Despite advances in surgery, radiation, and immunotherapy, patients with HPV-negative HNSCC continue to face poor outcomes, with five-year overall survival rates often below 55%. Adoptive cell therapy (ACT) in solid tumors remains limited by the scarcity of tumor-reactive T cells and their functional exhaustion after expansion. The sentinel lymph node (SLN), the initial site of tumor antigen presentation and T-cell priming, may provide a rich and minimally exhausted source of tumor-specific lymphocytes. Here, we evaluated the immunologic and therapeutic advantages of SLN-derived leukocytes over those from tumor tissue in an orthotopic model of HPV⁻ HNSCC.\nMethods: CD45⁺ immune cells isolated from donor SLNs, NSLNs, tumors, or SLNs preconditioned with low-dose tdRT (4 Gy) in the 4MOSC1 murine model were adoptively transferred into syngeneic tumor-bearing recipients to evaluate their therapeutic potential. Recipient groups included untreated controls, preconditioned mice with 4 Gy tdRT, or a single PD-1 blockade (PD1i) dose before ACT. Phenotypic and functional characterization was performed using flow cytometry, multiplex immunofluorescence, ELISA, and CITE-seq to evaluate cell populations, activation, exhaustion, clonal overlap, and tissue distribution.\nResults: SLN-CD45⁺ populations were enriched in activated CD4⁺/CD8⁺ T cells with elevated CD69, CD137, and IFN-γ expression compared with tumor-derived counterparts. mIHC confirmed higher densities of activated T cells in SLN and tumor regions after SLN-CD45⁺ transfer. TCR analysis revealed substantial overlap between SLN and tumor clonotypes, suggesting selective enrichment of tumor-reactive clones. Functionally, ACT with SLN-CD45⁺ cells induced greater tumor regression and survival benefits than ACT from tumor source, even without lymphodepletion or expansion in culture. Notably, cryopreserved SLN-derived cells retained comparable efficacy to freshly isolated ones. Preconditioning recipients with 4 Gy tdRT or PD1i further improved intratumoral infiltration, activation, and persistence of transferred cells without added toxicity.\nConclusions: The sentinel lymph node provides a potent, readily accessible reservoir of tumor-reactive immune cells for ACT. Combining SLN-derived ACT with tdRT and PD1i significantly enhances therapeutic efficacy in HPV⁻ HNSCC. These findings highlight the translational potential of leveraging tumor-draining lymphoid niches as tumor-primed immune reservoirs for next-generation ACT in solid tumors.", "source_company": "University of California San Diego", "source_org_type": "大学", "row_number": 1092, "target_meta": "PD1", "MOA_meta": "抑制剂"}, {"drug_name": "E6R", "company": "Dana-Farber Cancer Institute", "org_type": "医院", "target": "SIN3-HDAC", "modality": "inhibitor", "importance_level": "中", "total_score": 53.5, "institution_score": 35, "track_score": 75, "milestone_score": 60, "field_heat_score": 70, "bonus_score": 5, "brief_reason": "E6R为首创非酶活性SIN3-HDAC复合物调控剂，通过破坏SIN3 PAH2域相互作用实现选择性去抑制，具有比传统HDAC抑制剂更高的选择性和更少转录组干扰。新机制+选择性抗肿瘤活性为亮点，但研发机构为学术医院而非商业公司，处于preclinical阶段。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/7973", "id": "zZ7M_5wBZznHJdnt_W3O", "source_drug_name": "E6R", "title": "Targeting non-enzymatic HDAC-mediated repression reveals a selective stress-adaptive mechanism for cancer therapy", "abstract_text": "Purpose: Enzymatic pockets, such as those found in histone deacetylases (HDACs), have long served as attractive targets for drug discovery. However, conventional HDAC inhibitors often lack selectivity and cause systemic toxicity due to paralog redundancy and their incorporation into multi-subunit transcriptional regulatory complexes. To identify more selective modulators, we performed an unbiased yeast genetic screen of ~52,000 compounds by interrogating the activity of the conserved HDAC/Rpd3L complex. Follow-up mechanistic studies uncovered hits that do not directly inhibit HDAC catalytic activity but instead modulate repression through alternative mechanisms. We subsequently evaluated the lead compound, E6R, in human neuroblastoma cells and mouse xenografts, benchmarking against the enzymatic inhibitor TSA in vitro and Vorinostat (SAHA) in vivo. These studies demonstrate that E6R, a first-in-class non-enzymatic SIN3-HDAC modulator, achieves comparable anti-tumor efficacy with far greater selectivity and minimal global transcriptional disruption.\nMethods: E6R was evaluated in yeast and SK-N-BE(2)-C neuroblastoma cells using bulk and single-cell RNA-seq (Seq-Well S3), SIN3A ChIP-seq, viability and invasion assays, and mouse xenografts.\nResults: In yeast, E6R disrupts Sin3/Rpd3L-dependent transcriptional repression without inhibiting HDAC catalytic activity. In human neuroblastoma cells, E6R produced anti-tumor activity comparable to TSA. Transcriptomically, E6R modulated ~14-fold fewer genes than TSA and caused minimal global perturbation. Interestingly, E6R selectively activated stress- and senescence-associated programs governed by the ATF4-driven integrated stress response (ISR), including GDF15, DDIT3, ATF3, and FGF21, while inducing minimal off-target effects. SIN3A ChIP-seq revealed promoter-proximal loss of SIN3A binding at several ISR loci, most notably GDF15 (~55 bp upstream of the TSS), consistent with direct de-repression through dissociation of the SIN3-HDAC complex. Although both compounds shared repression of E2F, MYC, and glycolytic targets and activation of p53, TNFα/NF-κB, and apoptotic signaling, E6R induced a distinct stress-adaptive state through an HDAC-independent mechanism. Functionally, E6R significantly reduced neuroblastoma cell invasion and tumor growth with limited cytotoxicity. In vivo, E6R inhibited neuroblastoma xenograft growth comparably to Vorinostat, supporting non-enzymatic HDAC modulation as a therapeutic alternative.\nConclusions: Together, these data strongly suggest that E6R is a selective, non-enzymatic SIN3-HDAC modulator that reprograms chromatin from a repressive to a stress-adaptive, anti-proliferative state, offering a mechanistically distinct and potentially safer framework for HDAC-targeted cancer therapy.", "source_company": "Dana-Farber Cancer Institute", "source_org_type": "医院", "row_number": 1097, "target_meta": "Sin3,HDAC", "MOA_meta": "抑制剂"}, {"drug_name": "FMNL1-overexpressing CAR-T cells", "company": "The University of Colorado School of Medicine", "org_type": "大学", "target": "未披露", "modality": "CAR", "importance_level": "中", "total_score": 53.5, "institution_score": 35, "track_score": 75, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "通过过表达FMNL1增强CAR-T细胞在实体瘤中的浸润和疗效，属于细胞治疗热门赛道但靶点未披露。大学机构分数较低，但显示体内显著改善存活的preclinical里程碑，综合热度和机制优化带来一定加分。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4563", "id": "9p7M_5wBZznHJdnt_W3O", "source_drug_name": "FMNL1-overexpressing CAR-T cells", "title": "FMNL1 overexpression enhances tumor-specific TIL and CAR-T cell accumulation and therapeutic efficacy in solid tumors", "abstract_text": "Purpose: Adoptive T cell therapies such as tumor-infiltrating lymphocytes (TIL) and chimeric antigen receptor (CAR)-T cells show limited efficacy against solid tumors. This is due in part to physical barriers in solid tumors, including abnormal vasculature and dense extracellular matrix, which limit T cell infiltration and persistence within restrictive tumor microenvironments. We investigated whether overexpression of Formin-like-1 (FMNL1), a cytoskeletal regulator of T cell migration, could overcome these physical barriers and improve T cell accumulation and therapeutic activity in solid tumors.\nMethods: We engineered tumor-specific TILs and CAR-T cells to overexpress FMNL1 using a bioengineering platform. We first assessed control and FMNL1-overexpressing T cell activation, cytotoxicity, and restimulation in vitro. Then using murine tumor models, we evaluated tumor infiltration and therapeutic efficacy of adoptively transferred control and FMNL1-overexpressing TILs and CAR-T cells in melanoma and lung carcinoma models.\nResults: FMNL1-overexpressing T cells maintained normal activation and tumor cell killing compared to control T cells. In vivo, FMNL1 overexpression significantly increased TIL and CAR-T cell accumulation at melanoma and lung carcinoma solid tumor sites compared to controls. Importantly, adoptive transfer of FMNL1-overexpressing CAR-T cells prolonged survival in melanoma tumor-bearing mice relative to control CAR-T cells, in both immunodeficient and immunocompetent recipient mice.\nConclusions: This is the first demonstration that enhancing cytoskeletal dynamics via FMNL1 overexpression increases T cell accumulation in solid tumors and improves therapeutic efficacy. These findings highlight a novel, tumor antigen and CAR construct independent strategy to overcome physical barriers in the tumor microenvironment and suggest translational potential for improving CAR-T cell therapy in patients with solid tumors.", "source_company": "The University of Colorado School of Medicine", "source_org_type": "大学", "row_number": 1123, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "miniproteins targeting mutant p53-R175H peptide-MHC-I complex", "company": "University of Minnesota Medical School", "org_type": "大学", "target": "mutant p53-R175H peptide-MHC-I complex", "modality": "miniprotein", "importance_level": "中", "total_score": 53.5, "institution_score": 35, "track_score": 85, "milestone_score": 45, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "靶向突变p53-R175H肽-MHC-I复合物的新型miniprotein，通过AI de novo设计用于癌免疫治疗，靶点为难成药胞内癌基因的neoantigen呈现，具有高创新性和免疫治疗潜力。机构为大学非商业顶级，preclinical早期阶段但AI平台集成和验证中导致总分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3538", "id": "TZ7M_5wBZznHJdnt_W7P", "source_drug_name": "miniproteins targeting mutant p53-R175H peptide-MHC-I complex", "title": "AI-driven de novo design of miniproteins targeting mutant p53 peptide-MHC-I complex for cancer immunotherapy", "abstract_text": "Genetic alterations in the tumor suppressor p53 occur in nearly every type of human cancer, with mutation rates ranging from 10% to nearly 100%, averaging about 50% in cancer patients. Over 80% of these mutations are missense mutations in the p53 DNA-binding domain (DBD), with the p53-R175H mutation being the most common \"hot spot,\" occurring in approximately 5% of p53-mutated cases. Clinically, p53-R175H mutation in cancer patients are significantly associated with decreased overall survival compared to cancer patients with wild-type p53. Biologically, missense mutations in the p53 gene, particularly \"hot-spot\" mutations, including p53-R175H, result in the high expression of mutant p53 protein in cancer cells. These features suggest that expression of mutant p53-R175H protein could serve as an attractive therapeutic target. However, targeting the intracellular oncoprotein mutant p53-R175H has proven extremely challenging and remains a major unmet need in cancer therapy. Interestingly, the mutant p53-R175H protein can be processed by the proteasome into a 9-mer peptide, presented on the cancer cell surface by human leukocyte antigen (HLA)-A*02:01, a common major histocompatibility complex (MHC) class I allele in the U.S. population (40%), providing a “unique” target for immunotherapy by harnessing immune cells—such as T cells—to eliminate cancer cells carrying mutant p53R-175H. Traditional efforts to develop T cell receptors (TCRs) or monoclonal antibodies (mAbs) against the peptide-MHC-I complex have largely failed due to low affinity, limited specificity, and multi-year development timelines. Recent advances demonstrate that artificial intelligence (AI)-designed miniproteins (less than 150 amino acids) targeting peptide-MHC class I complexes can be engineered into chimeric antigen receptor (CAR)-T cells, enabling robust T-cell activation and potent recognition and elimination of tumor cells. To accelerate the discovery of miniprotein-mediated therapeutics, we have developed and integrated multiple AI-driven platforms for de novo design of p53-R175H peptide-MHC-I-complex binding miniproteins, including diverse backbone generation, protein sequence optimization, and enhanced high-throughput computational screening of peptide-MHC-I-miniprotein complexes. Top candidates have undergone, or are currently undergoing, experimental validation as engineered T/NK cell engagers and CAR-T/NK cells to kill cancer cells. In summary, our integrated AI-driven framework enables rapid and personalized cancer immunotherapy by transforming previously “undruggable” intracellular oncoproteins—including, but not limited to, mutant p53—into actionable immunotherapeutic targets.", "source_company": "University of Minnesota Medical School", "source_org_type": "大学", "row_number": 1179, "target_meta": "MHC-I", "MOA_meta": "其他"}, {"drug_name": "HMCD-ART1", "company": "Cedars-Sinai Medical Center", "org_type": "医院", "target": "未披露", "modality": "other", "importance_level": "中", "total_score": 53.5, "institution_score": 35, "track_score": 65, "milestone_score": 70, "field_heat_score": 60, "bonus_score": 4, "brief_reason": "HMCD-ART1为七甲基菁染料偶联青蒿素的肿瘤靶向递送偶联物，通过OATPs介导的缺氧肿瘤特异性富集，实现线粒体亚细胞毒性，机制新颖用于克服mCRPC耐药。机构为医院学术型得分较低，但preclinical体内外数据扎实且显示显著疗效和安全性，赛道为新型递送+ROS机制有一定热度。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8796", "id": "f57M_5wBZznHJdnt_W7P", "source_drug_name": "HMCD-ART1", "title": "Subcellular targeted therapy using HMCD-artemisinin conjugates for metastatic castration-resistant prostate cancer", "abstract_text": "Background: Resistance to androgen-deprivation therapy leads to metastatic castration-resistant prostate cancer (mCRPC), a lethal stage with limited treatment options. Artemisinin (ART) derivatives exert anti-tumor activity through reactive oxygen species (ROS) generation and mitochondrial disruption but lack tumor selectivity. Our laboratory identified a near-infrared (NIR) heptamethine carbocyanine dye (HMCD) that preferentially accumulates in tumors via organic anion-transporting polypeptides (OATPs) upregulated under hypoxia, enabling tumor-specific delivery.\nMethods: To achieve subcellularly targeted chemotherapy, four HMCD-ART conjugates with distinct linkers were synthesized: HMCD-ART1 (artesunate linker), HMCD-ART2 (carbamate linker), HMCD-ART3 (ether linker), and HMCD-ART4 (ester linker). These were evaluated in androgen-independent prostate cancer models (22Rv1, PC-3, C4-2B, and resistant derivatives). Cytotoxicity, selectivity, and chemosensitization were analyzed in vitro, while subcellular localization, ROS generation, and cell-death mechanisms were examined by fluorescence microscopy, flow cytometry, and Western blotting. Tumor targeting and therapeutic efficacy were determined by NIR imaging and 22Rv1 xenograft models.\nResults: Among the conjugates, HMCD-ART1 showed the greatest potency and selectivity, effectively killing taxane-, abiraterone-, and enzalutamide-resistant prostate cancer cells while sparing normal prostate epithelial cells. HMCD-ART1 enhanced sensitivity to chemotherapeutics, inhibited colony formation and migration, and demonstrated prolonged tumor retention for up to eight weeks. Mechanistic analyses revealed mitochondrial and lysosomal co-localization, ROS induction, cytochrome c release, DNA damage (pATM, γH2AX), and mitochondrial-fission-dependent necrotic death. In vivo, HMCD-ART1 significantly suppressed xenograft tumor growth without observable systemic toxicity.\nConclusion: HMCD-ART1 integrates NIR-guided tumor targeting with mitochondrial-specific cytotoxicity, providing a novel therapeutic platform to overcome drug resistance in mCRPC. This strategy represents a next-generation precision chemotherapeutic approach combining targeted delivery, subcellular selectivity, and enhanced safety.", "source_company": "Cedars-Sinai Medical Center", "source_org_type": "医院", "row_number": 1210, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "rebecsinib", "company": "UC San Diego", "org_type": "大学", "target": "ADAR1", "modality": "inhibitor", "importance_level": "中", "total_score": 53.5, "institution_score": 35, "track_score": 75, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "rebecsinib为ADAR1剪接抑制剂（小分子），针对癌症干细胞自renewal和新机制靶点ADAR1p150。大学机构分数较低，但ADAR1相关癌症干性调控赛道具创新性，preclinical在太空实验及人源化模型中显示防肿瘤传播价值，已有IND支持。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6801", "id": "HJ7M_5wBZznHJdnt_W7O", "source_drug_name": "rebecsinib", "title": "Predicting and preventing cancer stemness in low Earth orbit", "abstract_text": "Cancer stemness properties, including enhanced survival, malignant regeneration, telomere deregulation, genomic and epitranscriptomic instability, fuel metastases, and have been linked to stress, retrotransposon and inflammatory cytokine activation, which can occur in low earth orbit (LEO). In NASA Axiom 1, 2 and 3 missions to the ISS, confocal imaging, WGS, RNA-seq and scRNA-seq of lentiviral FUCCI2BL cell cycle and ADAR1-GFP reporter transduced erythroleukemia (TF-1a), colorectal (Caco-2) and metastatic breast cancer (MBC; MDA-MB-231 and patient samples) revealed proliferation, significant genomic instability, HERV and LINE-1 retrotransposon deregulation, and APOBEC3C and ADAR1 activation. Moreover, in Axiom 2 and 3 missions with ADAR1-reporter expressing MBC organoids and in humanized MBC mouse models, an ADAR1p150 splicing modulator, rebecsinib (IND 153126), prevented tumor propagation. Thus, cancer studies in LEO may accelerate the development of innovative cancer therapeutics and countermeasures for long-term spaceflight.", "source_company": "UC San Diego", "source_org_type": "大学", "row_number": 1283, "target_meta": "ADAR", "MOA_meta": "抑制剂"}, {"drug_name": "polyhistidine-directed degrader platform (HisTAC)", "company": "University of Florida", "org_type": "大学", "target": "polyhistidine tag (His-tag)", "modality": "other", "importance_level": "中", "total_score": 53, "institution_score": 25, "track_score": 85, "milestone_score": 65, "field_heat_score": 75, "bonus_score": 4, "brief_reason": "HisTAC利用Ni²⁺-NTA结合聚组氨酸标签实现配体非依赖的靶向蛋白降解，针对难成药靶点展示通用性。大学机构得分较低，但新型tag-based degrader平台机制创新且preclinical数据扎实，赛道热度较高故总分处于中位。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6561", "id": "_lXM_5wBX1NQZOEH-LC5", "source_drug_name": "polyhistidine-directed degrader platform (HisTAC)", "title": "Development of polyHis-targeting chimeras (HisTACs) for targeted protein degradation", "abstract_text": "Induced-proximity degraders hold great promise for oncology, yet their utility remains constrained by the need for high-affinity ligands for each protein of interest. Tag-based degrader systems provide ligand-independent surrogates but are limited by large tag size, risk of tag-driven ubiquitination, and difficulty of engineering substantial tags into endogenous genes. To address these challenges, we developed a polyhistidine-directed degrader platform (HisTAC) that uses Ni²⁺-nitrilotriacetic acid (Ni²⁺-NTA) to engage His-tagged proteins and recruit CRBN or VHL E3 ligases.Cellular uptake was first confirmed with a fluorescent His₆-CPP/Ni-NTA probe, which exhibited rapid entry and widespread intracellular distribution. We then generated a HeLa cell line with endogenously His₆-HiBiT-tagged BRD4 and screened a panel of Ni²⁺-NTA-based degraders. Constructs containing two Ni²⁺-NTA groups displayed the highest potency, yielding >50% BRD4 loss at micromolar levels. MG-132 co-treatment fully blocked BRD4 depletion, confirming proteasome dependence. Immunoblotting further revealed preferential degradation of BRD4 long isoform, with moderate reduction of the short isoform. VHL-recruiting HisTACs also induced potent, isoform-selective BRD4 degradation with sub-micromolar efficacy toward the long isoform.To test the generalizability of this platform, we engineered a polyHis-HiBiT-tagged PSPC1 cell line—an RNA-binding protein lacking tractable ligands. Both CRBN- and VHL-based HisTAC degraders induced rapid, dose-dependent PSPC1 degradation, demonstrating the applicability of Ni²⁺-NTA-guided proximity to traditionally “undruggable” targets.\nTogether, these results establish HisTAC degraders as a versatile, ligand-independent strategy for probing challenging cancer targets and accelerating degrader discovery and mechanistic studies in cancer research.", "source_company": "University of Florida", "source_org_type": "大学", "row_number": 308, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "miR-148b inhibitor", "company": "Mayo Clinic", "org_type": "医院", "target": "miR-148b", "modality": "other", "importance_level": "中", "total_score": 53, "institution_score": 35, "track_score": 65, "milestone_score": 75, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "药物为miR-148b抑制剂，通过上调肿瘤抑制因子GRK2抑制MALT1活性，针对ABC-DLBCL；Mayo Clinic医院机构基础分较低，但体外+体内瘤模型抑制肿瘤生长显示较强preclinical里程碑，miRNA抑制剂在淋巴瘤领域有一定创新性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/2348", "id": "9FXM_5wBX1NQZOEH-LG6", "source_drug_name": "miR-148b inhibitor", "title": "MicroRNAs targeting tumor suppressor GRK2: Novel potential therapeutic strategies for restraining MALT1-dependent DLBCL", "abstract_text": "Introduction/Objectives: The CARMA1-BCL10-MALT1 (CBM) signalosome plays crucial role in mediating antigen receptor-induced activation of NF-κB transcription factor and subsequent lymphocyte activation. The effector protein of the signalosome, MALT1, functions both as a scaffold to recruit downstream NF-κB signaling machinery, and as a protease to cleave and inactivate multiple substrates including negative regulators of NF-κB. Constitutive MALT1 activation, which can occur as a result of gain-of-function mutations of the B cell receptor, CARMA1, BCL10 or chromosomal translocation involving the MALT1 gene, underlies the pathogenesis of multiple lymphoid malignancies including activated B-cell type-diffuse large B-cell lymphoma (ABC-DLBCL) and MALT lymphoma. We previously identified G-protein-coupled receptor kinase 2 (GRK2) as a tumor suppressor in MALT1-dependent lymphomas which binds MALT1 and inhibits MALT1 scaffolding and proteolytic activities. Accordingly, GRK2 mRNA levels are markedly lower in a subset of DLBCL tumors compared to normal B cells and lower GRK2 level in ABC-DLBCL is associated with reduced patient survival. In current study, we sought to investigate the mechanism of how GRK2 levels are regulated in ABC-DLBCL. Methods/Results: Using DICER1 depleted cells, we showed that globally impaired miRNA processing leads to increased GRK2 protein levels. We then conducted bioinformatic analyses of patient tumor samples and performed screening via microRNA Data Integration Portal to identify microRNAs that target GRK2 in ABC-DLBCL. Further GRK2 3’UTR reporter assay confirmed direct targeting of GRK2 by candidate miRNAs. ABC-DLBCL cell lines, OCI-LY3 and TMD8, which demonstrate reduced GRK2 mRNA expression compared to primary B cells, show elevated expression of candidate GRK2-targeting microRNAs. Stable overexpression of miR-125a, 125b, or 148b in OCI-LY3 or TMD8 cells led to reduced GRK2 expression, enhanced MALT1 activity and increased cell proliferation. Conversely, in vitro inhibition of candidate miRNAs using anti-miRNA Locked Nucleic Acids (LNA) inhibitors led to enhanced GRK2 expression, reduced MALT1 activity and decreased cell proliferation. Importantly, treatment of mice with inhibitors of miR-125b and miR-148b abrogates the growth of ABC-DLBCL xenograft tumors in vivo. Conclusion: We have identified miRNAs that negatively regulate GRK2 expression in ABC-DLBCL. These GRK2-targeting miRNAs serve a pro-tumorigenic role by promoting MALT1 oncoprotein’s scaffold and protease activity. Furthermore, inhibitors of these miRNAs can enhance GRK2 expression and thereby suppress MALT1 activity and MALT1-dependent tumor cell proliferation, both in vitro and in vivo. These studies suggest that microRNA inhibitors which enhance GRK2 expression could represent a novel approach for restraining MALT1-dependent lymphomagenesis.", "source_company": "Mayo Clinic", "source_org_type": "医院", "row_number": 480, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "an oligonucleotide therapeutic targeting long noncoding RNA TUG1", "company": "Nagoya University", "org_type": "大学", "target": "TUG1", "modality": "ASO", "importance_level": "中", "total_score": 53, "institution_score": 35, "track_score": 75, "milestone_score": 60, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "药物为靶向长链非编码RNA TUG1的ASO，用于复发性胶质母细胞瘤的I期研究，TUG1为胶质瘤中高表达的lncRNA，新机制靶向但非主流热门靶点。机构为大学非商业公司得较低分，赛道小核酸+脑瘤未满足需求有一定热度，I期启动体现初步临床进展。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/12059", "id": "HlXM_5wBX1NQZOEH-LK6", "source_drug_name": "an oligonucleotide therapeutic targeting long noncoding RNA TUG1", "title": "Investigator-initiated phase I trial of an oligonucleotide therapeutic targeting long noncoding RNA TUG1 for recurrent glioblastoma", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Nagoya University", "source_org_type": "大学", "row_number": 510, "target_meta": "TUG1", "MOA_meta": "反义疗法"}, {"drug_name": "anti-PD1", "company": "Broad Institute", "org_type": "研究机构", "target": "未披露", "modality": "inhibitor", "importance_level": "中", "total_score": 53, "institution_score": 35, "track_score": 85, "milestone_score": 40, "field_heat_score": 80, "bonus_score": 0, "brief_reason": "anti-PD1为PD-1抑制剂，但摘要未披露具体药物，仅讨论CD103+ Tfh-like细胞比例与anti-PD1疗效相关性。研究机构背景+preclinical机制洞察导致综合评分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8498", "id": "uFXM_5wBX1NQZOEH-LK6", "source_drug_name": "anti-PD1", "title": "Proteotranscriptomic dissection of breast cancer T cell states identifies CD103+ Tfh-derived cytotoxic CD4+ cells linked to immunotherapy response", "abstract_text": "While cancer immunotherapies have primarily focused on activation of cytotoxic CD8 killing, CD4 T cell activity is also associated with survival and immunotherapeutic response in numerous cancers. We applied integrated single-cell RNA sequencing and multiplexed protein epitope profiling to breast cancer samples to resolve the complexity of immune cell states within the tumor microenvironment. This approach enhanced phenotypic resolution, identifying three distinct states within the T follicular helper (Tfh) cell cluster. A CXCR4high progenitor state gave rise to two differentiated states: an IGFL2high subset resembling conventional Tfh cells and localised to B cell-rich lymphoid aggregates, and a CD103+ subset, exhibiting features of tissue residency, exhaustion, and cytotoxicity, which co-localised with tumor foci. CD103+ Tfh-like cells were found to interact with CXCL10+ macrophages through production of CCL chemokines and CSF1. A higher CD103+ Tfh to IGFL2high Tfh ratio correlated with improved patient survival and enhanced responses to anti-PD1 checkpoint blockade. These findings integrate Tfh and CD4 with cytotoxic potential in breast cancer, offering new insight into anti-tumor immunity and response to checkpoint blockade.", "source_company": "Broad Institute", "source_org_type": "研究机构", "row_number": 607, "target_meta": "not available", "MOA_meta": "抑制剂"}, {"drug_name": "recombinant monoclonal antibodies", "company": "MilliporeSigma", "org_type": "公司", "target": "未披露", "modality": "recombinant monoclonal antibodies", "importance_level": "中", "total_score": 53, "institution_score": 75, "track_score": 40, "milestone_score": 30, "field_heat_score": 50, "bonus_score": 0, "brief_reason": "该产品为MilliporeSigma的工具型重组单克隆抗体，用于IHC检测器官芯片中的蛋白如FOXA2、HNF4alpha、Keratin 7，非治疗药物而是研究试剂。机构为知名生命科学工具公司但非头部药物研发MNC，赛道为抗体工具而非热门治疗modality，故总体中等重要性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6993", "id": "61XM_5wBX1NQZOEH-LK6", "source_drug_name": "recombinant monoclonal antibodies", "title": "Characterizing organoid maturation and disease progression through recombinant monoclonal antibodies", "abstract_text": "Organoids are three-dimensional structures derived from either pluripotent stem cells or adult stem cells, consisting of multiple cell types that interact with one another. They are highly sought after for research in organ development, disease modeling, and drug testing. Organoids can be engineered to replicate specific disease conditions, enabling researchers to study disease progression and design therapeutic modalities. We have used recombinant monoclonal antibodies, produced using a proprietary B-cell immortalization technique and a high-yield expression system, for characterizing organoids. These antibodies provide consistent performance across various experimental conditions and exhibit high specificity and sensitivity, allowing for precise detection of target proteins in biological samples. They can be utilized to identify specific cell types during organoid development, study the time-dependent expression of proteins, and analyze the interactions among multiple cell types during development. We have examined organoid development and maturation through immunohistochemistry using selected recombinant antibodies. Immunohistochemistry analysis conducted on normal liver tissue sections, as well as progenitor and mature organoid sections, revealed remarkable staining patterns for targets such as FOXA2, HNF4alpha, and Keratin 7. These applications may significantly enhance our understanding of the mechanisms involved in tissue development and disease progression.", "source_company": "MilliporeSigma", "source_org_type": "公司", "row_number": 639, "target_meta": "not available", "MOA_meta": "单抗"}, {"drug_name": "CEACAM5-targeted ADC", "company": "UNSW", "org_type": "大学", "target": "CEACAM5", "modality": "ADC", "importance_level": "中", "total_score": 53, "institution_score": 35, "track_score": 85, "milestone_score": 45, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "该ADC靶向CEACAM5，属于当前热门的ADC赛道，具有较高技术热度。研发机构为大学，主要用于开发3D模型筛选平台而非药物本体推进，临床开发里程碑信息有限。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5499", "id": "R1XM_5wBX1NQZOEH-LO6", "source_drug_name": "CEACAM5-targeted ADC", "title": "Developing 3D cell models for high-throughput antibody-drug conjugate screening in cancer", "abstract_text": "Antibody-drug conjugates (ADCs) are a rapidly evolving class of biotherapeutics designed to deliver potent cytotoxic agents directly to cancer cells while minimizing systemic toxicity. ADCs offer this highly targeted approach by combining the selectivity of antibodies with the lethality of small-molecule drugs. However, their preclinical development still faces substantial challenges, including species-specific differences in antigen expression and antibody binding that complicate translational studies, often leading to discrepancies between preclinical efficacy and clinical outcomes. As a result, there is growing interest in developing more predictive preclinical models, including those that incorporate extracellular matrix (ECM) components into three-dimensional (3D) culture models which can help dissect how microenvironmental factors influence ADC target engagement. Such models provide a more physiologically relevant environment to assess ADC diffusion and payload delivery.\nUsing Inventia Life Science’s RASTRUMTM Allegro platform, we developed and validated the utility of high-throughput 3D bioprinted patient-derived colorectal cancer (CRC) models for the testing of a CEACAM5-targeted ADC in two CRC subtypes. These engineered hydrogel-based tumoroid models, using the GibcoTM OncoProTM CRC Tumoroid Cell Lines (ThermoFisher Scientific), were tuned to mimic the stiffness and ECM composition of CRC tumors and maintained subtype-specific molecular and phenotypic features. This allowed comparisons of ADC efficacy versus standard-of-care chemotherapies and here we show clinically-relevant differential drug responses between subtypes, with the ADC demonstrating enhanced cytotoxicity over chemotherapy alone.\nWe also provide evidence for the ease of assessing target expression in situ by immunofluorescence imaging of models. Furthermore, the ability to test on-target cytotoxicity dependence was demonstrated by blocking target binding with anti-CEACAM5, which reduced ADC cytotoxicity in the sensitive tumoroid models.\nThis scalable and reproducible workflow is applicable across many cancer types, and bridges the gap between oversimplified in vitro assays and complex in vivo systems, offering more predictive insights into ADC performance by using models that incorporate physical and biochemical features relevant in patient tumors.", "source_company": "UNSW", "source_org_type": "大学", "row_number": 702, "target_meta": "CEACAM5", "MOA_meta": "抗体偶联药物"}, {"drug_name": "Cetuximab-IR700", "company": "Hangzhou Institute of Medicine, Chinese Academy of Sciences", "org_type": "研究机构", "target": "EGFR", "modality": "ADC", "importance_level": "中", "total_score": 53, "institution_score": 45, "track_score": 75, "milestone_score": 35, "field_heat_score": 65, "bonus_score": 3, "brief_reason": "Cetuximab-IR700为EGFR靶向的近红外光免疫治疗ADC，可诱导肿瘤细胞焦亡并释放高度免疫原性的Pyro-EVs激活先天免疫。机构为国内研究机构非企业主体、仍处机制探索的preclinical阶段导致总体分值中等，但ADC+NIR-PIT+焦亡免疫新机制具备一定赛道热度和bonus。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/7554", "id": "cFXM_5wBX1NQZOEH-LS6", "source_drug_name": "Cetuximab-IR700", "title": "Pyroptosis-derived extracellular vesicles as key immunoactivators in near-infrared photoimmunotherapy", "abstract_text": "Background: Pyroptosis, a lytic and highly inflammatory form of programmed cell death, has emerged as a powerful mechanism for augmenting anti-tumor immunity. Although antibody drug conjugate (ADC)-mediated near-infrared photoimmunotherapy (NIR-PIT) can induce tumor-specific pyroptosis and enhance immune responses, the downstream mediators that bridge pyroptotic cell death to immune activation remain undefined. Here, we investigated whether pyroptosis-derived extracellular vesicles (Pyro-EVs) constitute a key immunostimulatory output of tumor pyroptosis and sought to define their molecular composition and immune-activating functions.\nMethods: Pyroptosis was induced in SCC7 murine carcinoma cells using Cetuximab-IR700, a clinically-approved NIR-PIT ADC. EVs released during pyroptosis were isolated by ultracentrifugation and characterized by NTA and nano-flow cytometry. Deep proteomic profiling with organelle-origin mapping, GO enrichment, and nuclear-cytoplasmic signature scoring was performed to define Pyro-EV identity. DNA cargo was examined by nano-flow cytometry, DNase-protection assays, and confocal microscopy. Immunological activity was evaluated by exposing macrophages to Pyro-EVs, followed by RNA-seq, ELISA, and Western blot assessment of nucleic-acid sensing pathways.\nResults: NIR-triggered pyroptosis induced rapid release of a distinct EV population, generating Pyro-EVs at 2-3x the abundance of basal EVs. Proteomics identified a pyroptosis-specific signature with 726 emergent proteins enriched for ribosomal subunits, chromatin components, and DNA-binding regulators, absent in apoptotic or necrotic EVs. These molecular hallmarks indicate nuclear rupture and cytoplasmic mixing, establishing Pyro-EVs as a unique class of lytic cell-death-derived vesicles. Pyro-EVs carried elevated levels of double-stranded nuclear DNA, confirmed by DNase resistance and colocalization with chromatin-binding proteins. Functionally, Pyro-EVs were strong activators of innate immunity, inducing broad M1-polarizing programs in macrophages. RNA-seq showed induction of TLR7/9, MyD88, IRAK1/4, and NF-κB-related genes; Western blot validated activation of the TLR7/9-MyD88-IRAK-p65 axis, and ELISA demonstrated increased secretion of TNF-α, IL-6, and other cytokines, confirming DNA-sensing-dependent innate immune activation.\nConclusions: This study identifies Pyro-EVs as a previously unrecognized, immunogenic vesicle class that emerges during NIR-PIT. Pyro-EVs are rich in nuclear DNA and chromatin-associated factors and serve as high-potency activators of macrophage TLR7/9 signaling, establishing them as a central mediator connecting pyroptotic tumor death to innate immune amplification. These findings redefine the immunobiology of pyroptosis and uncover Pyro-EVs as a mechanistic driver of pyroptosis-induced anti-tumor immunity.", "source_company": "Hangzhou Institute of Medicine, Chinese Academy of Sciences", "source_org_type": "研究机构", "row_number": 911, "target_meta": "EGFR", "MOA_meta": "抗体偶联药物"}, {"drug_name": "anti-PD-1", "company": "UT MD Anderson Cancer Center", "org_type": "医院", "target": "PD-1", "modality": "inhibitor", "importance_level": "中", "total_score": 53, "institution_score": 35, "track_score": 85, "milestone_score": 40, "field_heat_score": 80, "bonus_score": 0, "brief_reason": "anti-PD-1为经典免疫检查点抑制剂，靶向PD-1，赛道成熟且胃癌中已有临床应用，但本研究聚焦其耐药机制而非新药开发；机构为顶级肿瘤医院但非药企，开发阶段为机制研究而非药物推进，导致综合重要性中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9529", "id": "2J7M_5wBZznHJdnt_W3O", "source_drug_name": "anti-PD-1", "title": "CEACAM5/6+ cancer cell and IL1B+ macrophage-mediated resistance in anti-PD-1 treated gastric cancer", "abstract_text": "Immune checkpoint blockade therapy has shown limited efficacy in gastric cancer, with most patients developing resistance through mechanisms that remain incompletely defined. Here, we generate a comprehensive single-cell RNA sequencing atlas of 526,583 cells from gastric cancer patients treated with anti-PD-1 plus chemotherapy, analyzing paired pre- and post-treatment samples to capture dynamic resistance mechanisms. We identify two distinct resistance pathways that emerge during treatment. First, CEACAM5/6+ cancer cells are markedly enriched in pre-treatment non-responders and predict treatment failure. These CEACAM5/6+ epithelial cells show the highest tumor scores and correlate with increased regulatory T cell infiltration expressing CEACAM1, establishing an alternative checkpoint axis that bypasses PD-1/PD-L1 blockade. External validation in independent cohorts confirms CEACAM5/6 expression as a robust predictor of anti-PD-1 resistance. Second, we uncover a macrophage-driven inflammatory cascade central to treatment resistance. IL-1β+ macrophages serve as the primary source of NF-κB pathway activation across the tumor microenvironment, triggering downstream IL-6 production, Th17 cell differentiation, chronic inflammation and epithelial-mesenchymal transition. This macrophage module is significantly enriched in post-treatment non-responders, with TNF-high expressing monocyte-macrophages absent in responders but prevalent in resistant tumors. The resulting inflammatory milieu drives PD-L1 upregulation across multiple cell types, creating a self-reinforcing immunosuppressive niche. Collectively, these findings nominate CEACAM5/6⁺ epithelial cells and IL-1β⁺ inflammatory macrophages as actionable therapeutic targets for overcoming anti-PD-1 resistance in gastric cancer, providing a mechanistic framework and rational blueprint for next-generation combination immunotherapy strategies.", "source_company": "UT MD Anderson Cancer Center", "source_org_type": "医院", "row_number": 1106, "target_meta": "PD1", "MOA_meta": "抑制剂"}, {"drug_name": "anti-GARP antibody", "company": "Cancer Research UK Manchester Institute", "org_type": "研究机构", "target": "GARP", "modality": "antibody", "importance_level": "中", "total_score": 52.5, "institution_score": 35, "track_score": 75, "milestone_score": 45, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "药物为靶向肿瘤细胞表面GARP的抗体，通过阻断GARP/TGF-β轴减少TGF-β信号、解除免疫逃逸，促进CD8+ T细胞杀伤肿瘤。该研究机构非商业公司且仅停留在小鼠模型和患者样本分析阶段，赛道涉及热门TGF-β免疫调控靶点但缺乏临床进展导致总分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9474", "id": "s1XM_5wBX1NQZOEH-LK6", "source_drug_name": "anti-GARP antibody", "title": "Glucocorticoids inhibit the GARP/TGF-βaxis initiating immune-dependent melanoma control", "abstract_text": "Melanoma is the form of skin cancer responsible for most patient deaths. Treatment with immune checkpoint blockade (ICB) has led to a significant improvement in outcomes. However, half of melanoma patients do not derive long-term benefit, and improved understanding of this is required to identify novel mechanisms of resistance and treatment. We screened a range of topical treatments, used in non-melanoma skin diseases, for anti-cancer activity in an ICB-refractory murine melanoma model. In particular, and building on previous work by us and others, we focused on topical treatments that had the potential to influence the inflammatory response within tumors, which in turn may improve anti-tumor immune responses.\nIn a story recently published in Cancer Discovery, we found topical glucocorticoids to uniquely trigger acute tumor shrinkage. After just two doses, GC-treated tumors shrank, whereas control-treated tumors doubled in volume. Intriguingly, this effect was lost in Rag1-/- mice (deficient in B and T cells) or in mice depleted of CD8+T cells, uncovering a key role for T cells in GC-induced tumor growth control. Of eight cancer models tested for GC-responsiveness, half experienced immune-depended control, and half were unresponsive.\nGCs downregulated the expression of Glycoprotein A repetitions predominant (GARP) on the surface of melanoma cells. GARP is a cell-surface protein that plays a critical role in the activation of TGFβ from its inactive latent form. Targeted mutagenesis and genetic knockout confirmed GC-induced GARP downregulation reduced TGFβ signalling, allowing CD8+ T cell tumor killing. Of the eight tumor models tested, only the four GC-responsive tumors also responded to TGFβ inhibition, suggesting that GCs triggered immune-dependent tumor control when tumors make use of TGFβ signalling for immune evasion.\nUnpublished data expands on this story. We examined the efficacy of using an anti-GARP antibody in mice, with and without immunotherapy, in order to identify further translational opportunities of this finding. Moreover, we have examined in-house melanoma patient biopsies to identify the immune environment of GARPhigh tumors vs GARPlow tumors, and correlated this with response to immunotherapy.\nWe discovered a paradoxical immune-dependent shrinkage induced by GCs in certain tumor models. Given the widespread use of GCs in patients receiving immunotherapy, these unexpected findings have the potential to result in significant clinical impact. The GARP/TGFβ axis therefore represents a cancer-cell intrinsic immune evasive pathway targetable by steroids, and further studies investigating the approach of inhibiting GARP on tumor cells directly investigate its use as a therapeutic strategy.", "source_company": "Cancer Research UK Manchester Institute", "source_org_type": "研究机构", "row_number": 44, "target_meta": "CNGB1,GARP", "MOA_meta": "抗体"}, {"drug_name": "SMARCAL1 inhibitors", "company": "BellBrook Labs", "org_type": "公司", "target": "SMARCAL1", "modality": "inhibitor", "importance_level": "中", "total_score": 52.5, "institution_score": 45, "track_score": 75, "milestone_score": 35, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "SMARCAL1是新兴癌症免疫靶点，通过抑制可激活cGAS/STING通路并下调PD-L1表达，具有免疫治疗潜力。BellBrook Labs为assay开发服务公司而非药物研发主体，当前仅处于HTS assay建立和初步筛选阶段，缺乏临床进展。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6511", "id": "f1XM_5wBX1NQZOEH-LO6", "source_drug_name": "SMARCAL1 inhibitors", "title": "Development and validation of HTS assays for discovery of SMARCAL1 ATPase inhibitors", "abstract_text": "SWI/SNF-related matrix-associated actin-dependent regulator of chromatin subfamily A-like protein (SMARCAL1) is an ATP-dependent SNF2 motor protein family annealing helicase that maintains genomic stability during DNA replication by catalyzing fork regression and Holliday junction migration. Loss of SMARCAL1 and the attendant DNA damage has been shown to increase tumor immunity via stimulation of the cGAS/STING pathway and suppression of PDL-1 expression, making it an attractive target for cancer immunotherapy. Here we describe development of HTS-compatible assays for screening and profiling SMARCAL1 inhibitors using the Transcreener ADP2 Assay to measure DNA-dependent ATPase activity. The Transcreener ADP2 Assay directly detects ADP in a competitive immunoassay with far-red, fluorescence polarization (FP), fluorescence intensity (FI) or time-resolved Förster-resonance-energy-transfer (TR-FRET) readouts. This format is homogenous (mix-and-read), compatible with diverse DNA substrates, and resistant to interference from screening compounds. A human SMARCAL1 construct comprising the core catalytic domain plus the HARP1, HARP2 domains, produced in BaV-infected insect cells, showed robust ATPase activity in initial testing with synthetic forked DNA (fDNA) and sheared salmon sperm DNA (sssDNA); hydrolysis of ATP was completely dependent on the presence of DNA. The Km for ATP with either substrate was 110 μM, and the Km values for sssDNA and fDNA were 30 ng/ml and 38 pM, respectively. The enzyme showed remarkable catalytic rates (kcat) of 58.6 s-1 and 81.1 s-1 with the two respective DNA substrates, enabling the use of less than 100 pM enzyme to produce a robust signal under initial velocity conditions. The kinetic parameters determined using the three different assay readouts (FP, FI and TR-FRET) were in concordance. The FP assay was validated for HTS by screening a collection of 1280 bioactives, yielding a Z’ > 0.9 and identification of hits that were confirmed in dose response experiments.", "source_company": "BellBrook Labs", "source_org_type": "公司", "row_number": 56, "target_meta": "SMARCAL1", "MOA_meta": "抑制剂"}, {"drug_name": "GD2-CAR-macrophages", "company": "University of Malaya", "org_type": "大学", "target": "GD2", "modality": "CAR", "importance_level": "中", "total_score": 52.5, "institution_score": 25, "track_score": 80, "milestone_score": 70, "field_heat_score": 75, "bonus_score": 3, "brief_reason": "靶向GD2的CAR-巨噬细胞（CAR-M）通过增强吞噬和重塑TME展现对高危神经母细胞瘤的抗肿瘤活性。机构为大学得分较低，但CAR-M属于细胞治疗热门赛道且有较强体内疗效数据（包括生存延长和完全缓解），整体潜力中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1779", "id": "SJ7M_5wBZznHJdnt_W3O", "source_drug_name": "GD2-CAR-macrophages", "title": "Engineering macrophages as a novel therapeutic approach for high-risk neuroblastoma", "abstract_text": "Neuroblastoma (NB) accounts for 10% of pediatric cancer-related deaths. High-risk NB is frequently metastatic at diagnosis and has a poor 5-year survival rate (<50%) despite aggressive treatment. GD2, a disialoganglioside glycolipid that is expressed in nearly all NBs, has been validated as a promising immunotherapy target. Although GD2-CAR-T cells have been clinically evaluated, their efficacy has been limited by poor tumor infiltration and the immunosuppressive tumor microenvironment (TME), highlighting the need for alternative immune-based strategies. With inherent capacity of macrophages to infiltrate tumors, phagocytose cancer cells, and modulate TME, they represent a promising alternative strategy for immunotherapy in NB. In this study, we developed and evaluated GD2-CAR-macrophages (GD2-CAR-Ms) as a novel therapeutic approach for NB. GD2-specific CAR constructs were designed, validated, and introduced into multiple human and murine monocyte/macrophage cell lines via lentiviral transduction. Fluorescent microscopy and flow cytometry confirmed a significant enhancement in the phagocytosis of GD2-high NB cells by GD2-CAR-Ms containing Hu3F8 single-chain variable fragment (scFv). A strong positive correlation was observed between GD2 expression levels on the target cells and phagocytosis efficiency of GD2-CAR-Ms, indicating that the phagocytic activity of GD2-CAR-Ms is antigen-specific. Anti-tumor efficacy was further evaluated in vivo using an immunocompetent Mycn-expressing NB non-genetically engineered mouse model (MYCN-NGEMM). Mice treated with GD2-CAR-Ms exhibited significantly reduced tumor burden and prolonged survival compared to control groups. Notably, treatment of mice bearing GD2-high tumors resulted in markedly improved survival, including one complete remission among ten treated animals, underscoring the therapeutic potential of GD2-targeted macrophage therapy. Histological analysis showed increased deposition of connective tissues and decreased tumor cells density, suggesting TME remodeling. Furthermore, immunohistochemistry reveals increased immune cell infiltration, particularly of macrophages, neutrophils and T cells, indicating a favorable shift in the immune TME from “cold” to “hot” following GD2-CAR-M treatment. Additionally, inhibition of tumor growth was also observed in our zebrafish NB model after GD2-CAR-Ms treatment, further supporting their therapeutic potential. Together, our findings demonstrate that GD2-CAR-Ms exhibit potent antitumor activity and reshape the tumor immune microenvironment, supporting their translational potential as a therapeutic strategy for high-risk NB.", "source_company": "University of Malaya", "source_org_type": "大学", "row_number": 83, "target_meta": "GD2", "MOA_meta": "其他"}, {"drug_name": "ANT308-Fc3", "company": "Georgia Institute of Technology", "org_type": "大学", "target": "VPAC", "modality": "other", "importance_level": "中", "total_score": 52.5, "institution_score": 30, "track_score": 75, "milestone_score": 70, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "ANT308-Fc3为VPAC受体拮抗剂（VIP/VPAC信号通路抑制剂），通过阻断新型吞噬检查点恢复巨噬细胞对TP53突变AML的吞噬作用，并在体内模型中实现高达65%的白血病清除。大学机构分数较低，但新型免疫检查点机制+preclinical显著疗效+高危AML未满足需求使赛道和里程碑具备一定热度。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5258", "id": "L57M_5wBZznHJdnt_W7O", "source_drug_name": "ANT308-Fc3", "title": "VIP/VPAC signaling as a phagocytosis checkpoint in TP53-mutated acute myeloid leukemia", "abstract_text": "Background: Acute myeloid leukemia (AML) remains one of the most lethal hematologic malignancies, especially in TP53-mutated disease where standard chemotherapy provides poor long-term survival. Immune evasion by myeloid cells in the tumor microenvironment is a major barrier to cure. We hypothesized that targeting vasoactive intestinal peptide (VIP)/VIP receptor (VPAC) signaling would overcome myeloid cell-mediated immunosuppression and enhance anti-tumor responses in AML.\nMethods: RNA-seq differential expression, survival analyses, and flow cytometry of AML bone marrow and PBMC were used to profile VIP/VPAC expression and myeloid versus blast compartments in TP53-mutated and non-mutated cases. TP53-wildtype and TP53 loss-of-function human and murine AML cell lines were used to measure VIP production by ELISA and macrophage phagocytosis of VIP-producing versus low-VIP cells in M1- and M2-like co-culture assays. In vivo efficacy of the long-acting VIP receptor antagonist ANT308 and its IgG4 Fc fusion ANT308-Fc3 was evaluated in C1498 and WEHI3 AML models, including VIP, VPAC1, and VPAC2 knockout hosts.\nResults: VIP expression was elevated in PBMC from ~36% of AML patients compared with healthy donors and was enriched in TP53-mutated cases. High VIP expression and TP53 loss-of-function each associated with inferior survival in cBioPortal datasets. RNA-seq showed that TP53-mutated AML is characterized by increased VIP and immunoregulatory pathway signatures together with reduced apoptosis and effector CD8⁺ T-cell-associated genes. Secretome analysis of human leukemia cells demonstrated higher VIP secretion from TP53 loss-of-function lines than from TP53-wildtype THP-1, confirming leukemia-intrinsic VIP production. In patient samples, both CD34⁺ blasts and CD34⁻ myeloid cells contained VIP⁺ cells, but non-blast myeloid cells accounted for most VIP⁺ events, indicating they are a major VIP source in the AML microenvironment. ANT308 enhanced phagocytosis of VIP-secreting WEHI3 leukemia cells by both M1- and M2-like macrophages but did not alter phagocytosis of VIP-low C1498 cells, supporting VIP as a phagocytosis checkpoint in AML. Consistent with a host contribution, VIP-, VPAC1-, or VPAC2-knockout mice bearing C1498 leukemia showed improved survival relative to wild-type mice. In vivo treatment of wild-type C1498-bearing mice with ANT308 or the long-acting Fc fusion ANT308-Fc3 eradicated established leukemia in up to 65% of animals.\nConclusions: VIP/VPAC signaling defines a previously unrecognized phagocytosis checkpoint that reinforces myeloid immunosuppression in AML and is linked to TP53-mutated disease. VPAC antagonism with ANT308-Fc3 restores macrophage phagocytosis and produces durable leukemia control in preclinical models, supporting clinical development of VPAC-targeted immunotherapy for high-risk AML.", "source_company": "Georgia Institute of Technology", "source_org_type": "大学", "row_number": 97, "target_meta": "VIPR2,VIPR1", "MOA_meta": "其他"}, {"drug_name": "13-F7-A", "company": "Tonix Pharmaceuticals, Inc.", "org_type": "公司", "target": "BTLA", "modality": "monoclonal antibody", "importance_level": "中", "total_score": 52.5, "institution_score": 45, "track_score": 75, "milestone_score": 35, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "靶点为免疫检查点BTLA，新型单抗阻断BTLA-HVEM相互作用增强抗肿瘤免疫；Tonix为中小型biotech公司（非头部MNC），赛道为新兴检查点抑制剂有一定热度，但仅体外表征preclinical阶段无临床进展。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9459", "id": "m1XM_5wBX1NQZOEH-LS6", "source_drug_name": "13-F7-A", "title": "In vitro characterization of fully human antagonistic anti-BTLA monoclonal antibodies", "abstract_text": "Introduction: B and T lymphocyte attenuator (BTLA) is an immune checkpoint receptor essential for immune homeostasis and tolerance. Unlike PD-1 or CTLA-4, BTLA is broadly expressed on lymphoid and some myeloid cells, including T cells, B cells, dendritic cells, and macrophages. Engagement with its ligand HVEM (herpesvirus entry mediator) transmits inhibitory signals that suppress immune activation. Within tumors, BTLA contributes to immune evasion by dampening anti-tumor responses. Given its unique expression profile and regulatory function, we developed monoclonal antibodies (mAbs) targeting BTLA as an immunotherapeutic strategy to enhance anti-tumor immunity.\nMethods: Fully human anti-BTLA mAbs identified by hybridoma screening were reformatted as huIgG4 (S228P/L235A) and transiently expressed using Curia’s TunaCHO® platform. The S228P mutation prevents Fab-arm exchange, stabilizing mAb structure, while L235A minimizes FcγR binding and effector functions. Binding potency was determined by ELISA; kinetics by Octet® biolayer interferometry (BLI) against human and cynomolgus BTLA. BLI also assessed FcγR, FcRn (at pH 6.0 vs 7.2), and C1q binding to evaluate recycling potential and complement activation. Neutralization of HVEM binding to BTLA was quantified by modified ELISA and cell-based reporter assays.\nResults: Six fully human anti-BTLA mAbs and a clinical candidate comparator JS004 displayed similar ~1 nM binding potencies (IC50) values to human and cyno BTLA by ELISA. Clone 13-F7-A exhibited the highest affinity (Kd < 1 nM) for both human and cyno BTLA among all 7 mAbs tested. Four mAbs and the comparator JS004 were high affinity binders to human and cyno BTLA (Kd 1-32 nM). All six fully human mAbs exhibited reduced FcγR binding relative to JS004. Each bound FcRn at pH 6.0 but not at 7.2, consistent with normal endosomal recycling. None bound C1q, whereas a positive-control IgG1 did bind to C1q as expected. In an ELISA-based biofunctional assay, all mAbs blocked HVEM binding to BTLA with similar IC50 values (~1 nM).\nConclusions: We generated potent, high affinity, human/cyno cross-reactive, fully human antagonistic anti-BTLA mAbs. Targeting BTLA offers promising opportunities for cancer immunotherapy and may demonstrate strong synergy when combined with other checkpoint antagonists, potentially overcoming resistance mechanisms and improving clinical outcomes.", "source_company": "Tonix Pharmaceuticals, Inc.", "source_org_type": "公司", "row_number": 258, "target_meta": "BTLA", "MOA_meta": "单抗"}, {"drug_name": "Cas12a2", "company": "University of Utah School of Medicine", "org_type": "大学", "target": "RNA序列（程序化靶向特定转录本）", "modality": "other", "importance_level": "中", "total_score": 52.5, "institution_score": 35, "track_score": 85, "milestone_score": 45, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "Cas12a2是一种新型CRISPR核酸酶，通过RNA触发非特异性DNA切割实现癌细胞程序化杀伤，可靶向KRAS G12C等转录本且对Sotorasib耐药细胞有效。机构为大学基础研究（低分），但新型机制+癌细胞特异性消除潜力处于热门CRISPR治疗赛道，前临床概念验证有一定强度，总分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4430", "id": "6FXM_5wBX1NQZOEH-LC5", "source_drug_name": "Cas12a2", "title": "Programmable RNA-triggered cancer cell elimination using CRISPR-Cas12a2", "abstract_text": "Selective eradication of cancer without harming healthy tissue is vital to precision oncology. Although traditional interventions such as chemotherapy or ionizing radiation are broadly applicable across many cancer types, they often exhibit off-target cytotoxicity; conversely, targeted small molecules and biologics improve specificity by binding to protein mutations, yet may not be as broadly applicable. Developing a therapeutic approach with both high specificity and broad applicability thus remains a major challenge in modern cancer care. Here, we show that Cas12a2, a recently discovered CRISPR nuclease exhibiting RNA-triggered DNA shredding, enables programmable sequence-specific elimination of mammalian cells expressing a target transcript. Target-expressing cultures electroporated with NLS-tagged Cas12a2 undergo massive cell death within five days. Activating Cas12a2 elicits widespread double-strand DNA breaks in the nucleus, leading to mitotic catastrophe, cellular inflammation, and apoptosis. We demonstrate that Cas12a2 distinguishes different RNA targets within heterogeneous cultures and induces cell death without observable off-target activity. Leveraging this approach, we eliminate NCI-H23 cancer cells harboring the prevalent oncogenic KRAS(G12C) point mutation, including cells with resistance to the FDA-approved KRAS(G12C) inhibitor Sotorasib. Taken together, these findings present Cas12a2 as a specific and broadly applicable therapeutic platform for personalized cancer treatment. These findings further establish the basis for use of Cas12a2 as a potent cell ablation tool across disciplines of basic and applied research.", "source_company": "University of Utah School of Medicine", "source_org_type": "大学", "row_number": 294, "target_meta": "RNA", "MOA_meta": "其他"}, {"drug_name": "anti-PD-L1", "company": "Seoul National University Bundang Hospital", "org_type": "医院", "target": "PD-L1", "modality": "inhibitor", "importance_level": "中", "total_score": 52.5, "institution_score": 35, "track_score": 85, "milestone_score": 40, "field_heat_score": 80, "bonus_score": 0, "brief_reason": "anti-PD-L1为PD-L1抑制剂，用于研究幽门螺杆菌介导的胃癌免疫治疗耐药机制，该研究揭示H.pylori降低抗PD-L1疗效的潜在作用。机构为医院科研型，得分较低；赛道为热门ICI领域且涉及耐药机制，热度高；处于基础与动物模型阶段，无临床里程碑，总分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/7518", "id": "PlXM_5wBX1NQZOEH-LG5", "source_drug_name": "anti-PD-L1", "title": "Helicobacter pylori-driven T cell stress in tumors as a mediator of resistance to immune checkpoint blockade in gastric cancer", "abstract_text": "The influence of microbiota residing within tumors on patient response to immunotherapies for gastric cancer (GC) is not yet fully understood. We aim to define the characteristics and functional role of tumor-resident microbiota in the context of immune checkpoint inhibitor (ICI) efficacy in GC. A comprehensive multi-omics analysis was performed on samples from 137 GC patients, all of whom were treatment-naïve regarding chemo- or antibiotics. This extensive dataset included both metagenomes and host transcriptomes, with single-cell RNA sequencing data. To achieve accurate quantification, we developed a novel tumor-resident microbial index (TM index) that compared taxon-level load between tumor tissue and matched normal tissue. Treatment responses were subsequently validated using syngeneic mouse models with a cancer-bacteria co-culture platform. Abundance analyses consistently highlighted Helicobacter pylori as the only species significantly decreased in tumor tissue compared to paired normal tissue. Metagenome-assembled genomes showed patient-specific H. pylori strains, maintaining over 99% genomic identity across the paired samples. The TMHP index indicated that high levels of H. pylori were predominantly found in the genomically stable (GS) subtype, characterized by a partially preserved normal physiology. Single-cell RNA sequencing data showed that H. pylori-infected cells exhibit a signature of elevated T cell stress, correlating with the overexpression of HSPA1A. Critically, H. pylori significantly compromised the therapeutic effectiveness of anti-PD-L1 by reducing the infiltration of T cells in mouse models. However, a negative effect was not observed with standard 5-fluorouracil or oxaliplatin treatments. Our findings implicate H. pylori as a mediator of immunotherapy resistance and a therapeutically actionable target for overcoming ICI resistance in GC.", "source_company": "Seoul National University Bundang Hospital", "source_org_type": "医院", "row_number": 351, "target_meta": "PDL1", "MOA_meta": "抑制剂"}, {"drug_name": "oHPs", "company": "University of Tokyo", "org_type": "大学", "target": "miR-21", "modality": "other", "importance_level": "中", "total_score": 52.5, "institution_score": 35, "track_score": 75, "milestone_score": 55, "field_heat_score": 70, "bonus_score": 4, "brief_reason": "oHPs为基于肿瘤特异性oncomiR（miR-21）触发的发夹DNA自组装系统，通过cGAS-STING通路选择性激活免疫杀伤肿瘤细胞。大学机构得分较低，但新型miRNA响应DNA自组装机制+肿瘤选择性免疫放大设计具有创新性和潜力，赛道热度较高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6558", "id": "zFXM_5wBX1NQZOEH-LG6", "source_drug_name": "oHPs", "title": "Selective oncolysis via oncomiR-driven DNA self assembly", "abstract_text": "Introduction: Artificial nucleic acids attract significant attention as cancer immunotherapy materials because they can be recognized by various extracellular and intracellular nucleic acid sensors and stimulate innate immune responses. However, their low selectivity for cancer cells causes severe systemic immunotoxicity, hindering the realization of immune cancer therapy using artificial nucleic acid molecules. To address this challenge, we propose a hairpin DNA self-assembly technology that induces cytotoxicity through cancer-selective immune activation. Here, we discuss cancer growth suppression via DNA self-assembly triggered by overexpressed oncomiRs.\nExperimental Design: Two hairpin DNA sequences were designed based on predictions of nucleic acid structural thermal stability (oHP-1 and oHP-2). This pair of hairpin DNAs (oHPs) triggered binding with one oncomiR, miR-21, forming a double-stranded DNA over 500 bp in length as a DNA aggregate. This structure is sufficiently large to induce innate immune activation. We examined the immune response induced by oHPs using cancer cells and tumor-bearing mice.\nResults: DNA aggregates formed by oHPs bound to cGAS within cancer cells that abundantly express miR-21. Consequently, IFN-β was produced through the cGAS-STING pathway, resulting in selective cell killing. When oHPs were administered into tumors of cancer-bearing mice using an appropriate DDS, tumor growth was strongly suppressed. CD8+ T cells and CD4+ T cells were observed to accumulate at the periphery of the tumor tissue. While sufficient tumor growth suppression was observed with oHPs alone, higher efficacy was observed when combined with anti-PD-1 antibody.\nConclusions: This approach represents the first technology enabling selective tumor lysis derived from intracellular DNA self-assembly, providing a potent therapeutic modality for cancer treatment. The engineered oHPs assemble into long double-stranded DNA via cancer-associated miR-21, functioning as a selective immune amplifier and booster circuit for targeted tumor lysis. This design exhibits non-responsiveness in miR-21-deficient cells and immunodeficient cells, demonstrating significant potential as an efficient targeted cancer therapy.", "source_company": "University of Tokyo", "source_org_type": "大学", "row_number": 456, "target_meta": "miR-21", "MOA_meta": "其他"}, {"drug_name": "self-delivering antisense oligonucleotide targeting STEAP2", "company": "The University of Texas Health Science Center At San Antonio", "org_type": "大学", "target": "STEAP2", "modality": "ASO", "importance_level": "中", "total_score": 52.5, "institution_score": 35, "track_score": 65, "milestone_score": 70, "field_heat_score": 60, "bonus_score": 2, "brief_reason": "药物为针对STEAP2的自递送ASO，通过敲低STEAP2抑制肝癌和前列腺癌细胞恶性行为并减小体内肿瘤生长，STEAP2作为金属还原酶在多种癌症中促瘤但非主流热门靶点。机构为大学非商业研发降低分数，ASO赛道有一定热度且有较强体外/体内preclinical证据支持中等重要性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10416", "id": "21XM_5wBX1NQZOEH-LG6", "source_drug_name": "self-delivering antisense oligonucleotide targeting STEAP2", "title": "Targeted STEAP2 knockdown with self-delivering antisense oligonucleotide reduces cancer malignant behavior", "abstract_text": "Background: The STEAP (Six-Transmembrane Epithelial Antigen of Prostate) family encodes metalloreductases involved in iron and copper metabolism, with increasing evidence linking dysregulated metal homeostasis to tumor progression. Increased STEAP2 expression has been implicated in the development and progression of several cancers, with enhanced cellular proliferation, migration, but its precise role in cancer remains obscure. The goal of this project is to investigate the significance and prognostic potential of targeting STEAP2 in oncogenesis.\nMethods: Our study investigated a self-delivering antisense oligonucleotide (ASO) targeting STEAP2 in cancer. Human liver cancer SNU398 and prostate cancer PC3 cells were treated with increasing ASO concentrations (0.25, 0.5, 1 and 5 μM) for 92 hours, followed by assessment of cell viability (WST-1), migration (transwell), and anchorage-independent growth (soft agar). For the in vivo study, orthotopic xenografts were created by injecting SNU398-luc/GFP cells into the livers of immunodeficient mice. Beginning on day 7, mice received 12 doses of the STEAP2-ASO or scrambled control (5 mg/kg, every two days). Tumor growth was monitored non-invasively via IVIS imaging. Upon treatment completion, tumors and adjacent liver tissues were harvested. Expression of EMT markers (Vimentin and SNAIL1) was evaluated in cell and tissue lysates using western blot analysis.\nResults: ASO mediated KD of STEAP2 induced a dose dependent reduction in STEAP2 expression, leading to significantly reduced cell viability, migration, and anchorage-independent growth in both SNU398 and PC3 cell lines. In addition, STEAP2 knockdown resulted in decreased expression of key EMT markers, including Vimentin and SNAIL1. In vivo analysis demonstrated that treatment with STEAP2 targeting ASOs resulted in a substantial decrease in tumor size, together with downregulation of STEAP2 levels, highlighting a clear association between STEAP2 suppression and inhibition of cancer progression. Consistent with the in vitro findings, tumors from ASO-treated mice also showed reduced Vimentin and SNAIL1 expression, further supporting EMT attenuation. Thus, our findings emphasize STEAP2 as an essential regulator of cancer development and progression as well as the therapeutic promise of the ASO-based STEAP2 silencing for abrogating the progression of liver and prostate cancer.\nConclusion: Overall, these findings establish STEAP2 as a potential biomarker and therapeutic target for the intervention of various cancers.", "source_company": "The University of Texas Health Science Center At San Antonio", "source_org_type": "大学", "row_number": 463, "target_meta": "STEAP2", "MOA_meta": "反义疗法"}, {"drug_name": "IFN-ICB", "company": "Kaohsiung Medical University", "org_type": "大学", "target": "未披露", "modality": "pro-immunocytokine", "importance_level": "中", "total_score": 52.5, "institution_score": 35, "track_score": 75, "milestone_score": 50, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "IFN-ICB为大学机构开发的pro-immunocytokine平台，通过蛋白酶可裂解连接子实现IFN与ICB（如anti-PD-1等）的肿瘤微环境特异性激活，上调MHC表达克服免疫治疗耐药。机构为大学得分较低，但赛道结合IFN+ICB创新形式及AI优化具较高热度，处于POC及小鼠模型验证阶段，综合潜力中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4507", "id": "dFXM_5wBX1NQZOEH-LK6", "source_drug_name": "IFN-ICB", "title": "A universal pro-immunocytokine platform using a spatial hindrance strategy to overcome MHC resistance and enhance efficacy", "abstract_text": "Immune checkpoint blockade (ICB) drugs are regarded as advanced approaches in cancer immuno-oncology (IO) therapy.\n(Background) However, they still face clinical limitations due to insufficient tumor selectivity, which can cause immune-related damage to normal tissues, and limited efficacy, particularly in tumors with major histocompatibility complex (MHC) loss that leads to immunotherapy resistance. While the interferon (IFN) family promotes immune activation and upregulates MHC expression, systemic administration often results in severe toxicities that restrict clinical application.\n(Methods) To address these challenges, we developed an innovative pro-immunocytokine (IFN-ICB) platform using a spatial hindrance strategy, in which IFN and ICB are linked via a protease-cleavable linker that mutually masks their activities. Upon protease-mediated cleavage within the tumor microenvironment, both IFN and ICB restore their activities and upregulate tumor MHC expression, thereby enhancing therapeutic efficacy while mitigating systemic toxicity.\n(Results) In our project, we initially demonstrated the proof of concept for pro-immunocytokine engineering by fusing IFNs to several ICBs, including anti-CTLA-4, anti-PD-1, and anti-PD-L1 antibodies. To optimize the blocking efficiency of IFN-ICBs, AI-based simulations were employed to predict spatial hindrance structures and calculate relevant blocking parameters. In vitro assessments confirmed that IFN-ICBs enhance tumor MHC expression and increase cytotoxicity. In vivo studies further demonstrated that IFN-ICBs efficiently improve antitumor efficacy in melanoma and colon cancer mouse models, indicating stronger immune responses within the tumor compared with either IFN or ICB monotherapy. Importantly, IFN-ICBs also reduced systemic toxicity and were safer than the combined administration of IFN and ICB drugs.\n(Conclusion) Our innovative pro-immunocytokine platform possesses the universal capability to transform any ICB or antibody into a pro-immunocytokine via AI-based prediction, enhancing therapeutic efficacy while improving safety, and thus holds promise to impact the next generation of IO therapeutics.", "source_company": "Kaohsiung Medical University", "source_org_type": "大学", "row_number": 562, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "C1", "company": "Albert Einstein College of Medicine", "org_type": "大学", "target": "SCFSkp2/Cks1", "modality": "inhibitor", "importance_level": "中", "total_score": 52.5, "institution_score": 35, "track_score": 75, "milestone_score": 55, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "C1为SCFSkp2/Cks1抑制剂，靶向该复合物在SCLC中调控神经内分泌表型及药物敏感性。大学机构得分较低，但靶点新颖且具肿瘤异质性调控机制，在preclinical模型显示体外/体内活性，综合热度中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4312", "id": "S57ECZ0BZznHJdntvNYd", "source_drug_name": "C1", "title": "The ubiquitin E3 ligase SCFSkk2/Cks1complex: A critical node coupling cell cycle control, tumorigenesis, and lineage fidelity in small cell lung cancer (SCLC)", "abstract_text": "Background: Mutation and inactivation of RB1 and TP53 are required and sufficient to drive small cell lung cancer (SCLC) tumorigenesis, both clinically and in mouse genetic models. We previously reported that the knockout of the Skp2 component of the ubiquitin E3 ligase SCFSkp2/Cks1 protected Rb1/Trp53-deficient mice from SCLC tumorigenesis but also increased the frequency of lung tumors with non-SCLC phenotypes. To explore this observation, we used a SCLC mouse model in which tumorigenesis was induced by CGRP-Cre-mediated deletions of Rb1, Trp53, and Pten (RPPt) in the neuroendocrine cells of the lungs. We crossed these to mice with either Skp2 knockout or the knockin (KI) of a mutated, inactivated SCFSkp2 accessory protein, Cks1 (Cks1N45R), that prevents the binding of p27 to SCFSkp2.\nMethods: We generated mouse lung cancer models using neuroendocrine cell-specific Rb1; Trp53; Pten triple-knockout mice with Skp2-KO or with Cks1N45R KI. Tumorigenesis, survival, and metastasis were monitored. Lung tumors were analyzed for neuroendocrine, SCLC subtype, squamous and other markers. Primary cell lines were established from lung tumors and characterized for lineage fidelity and sensitivity to cytotoxic and targeted drugs in vitro and in vivo.\nResults: Skp2 mRNA was elevated in human SCLC cell lines and PDXs. In RPPt mice, both Skp2-KO and Cks1N45R KI reduced lung tumor and liver metastasis incidence, increased survival, and caused a striking phenotypic shift. RPPt mouse tumors were SCLC with neuroendocrine staining. In contrast, tumors in both Skp2-KO and Cks1N45R KI mice lacked neuroendocrine markers and had squamous cell histology with staining for Sox2, KRT5, and p63. RPPt lung tumors were ASCL1+ and YAP1-. Conversely, the Skp2-inactivated tumors were ASCL1- and YAP1+ and retained SMARCA4 expression. Cell lines derived from the RPPt lung tumors grew more rapidly and were more sensitive to cisplatin and etoposide than were the lung tumor cells from the RPPt-Cks1N45R KI mice. The RPPt lung tumor cells were also more sensitive to growth inhibition by the SCFSkp2/Cks1 inhibitors C1 and pevonedistat and the CDK1/2/5/9 inhibitor dinaciclib. Finally, pevonedistat inhibited RPPt tumor growth in vivo.\nConclusion: These findings are consistent with the hypothesis that the Rb1/Trp53-deficient SCLC neuroendocrine phenotype is not a fixed feature but can vary with the presence of other oncogenic drivers, and document SCFSkp2/Cks1 as one such driver. This could reflect an early, deterministic lineage redirection toward a YAP1-high, SMARCA4-intact, non-neuroendocrine phenotype. SCFSkp2/Cks1 mediates lung cancer heterogeneity, plasticity and sensitivity to standard cytotoxic and targeted drugs. Furthermore, the in vivo efficacy of the neddylation inhibitor pevonedistat highlights SCFSkp2 complex assembly as a promising therapeutic target for SCLC.", "source_company": "Albert Einstein College of Medicine", "source_org_type": "大学", "row_number": 573, "target_meta": "CKS1B", "MOA_meta": "抑制剂"}, {"drug_name": "dual-siRNA therapeutic targeting WEE1 and PKMYT1", "company": "National Cancer Institute", "org_type": "研究机构", "target": "WEE1 和 PKMYT1", "modality": "siRNA", "importance_level": "中", "total_score": 52.5, "institution_score": 35, "track_score": 75, "milestone_score": 55, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "双siRNA靶向WEE1和PKMYT1实现合成致死机制，在弥漫性胸膜间皮瘤模型中显示协同抗增殖和促凋亡效应。NCI为研究机构得分较低，但RNA干扰+合成致死+局部递送平台具有一定赛道热度和概念验证里程碑价值。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3733", "id": "JFXM_5wBX1NQZOEH-LO6", "source_drug_name": "dual-siRNA therapeutic targeting WEE1 and PKMYT1", "title": "Dual siRNAs for precision targeting of synthetic lethal vulnerabilities in Diffuse Pleural Mesothelioma", "abstract_text": "Diffuse pleural mesothelioma (DPM) remains a lethal malignancy with limited benefit from existing therapies, underscoring the urgent need for molecularly precise treatments that act directly at the disease interface. Previously, we identified WEE1 and PKMYT1 as consistently overexpressed in DPM and demonstrated that their combined inhibition induces synthetic lethality. Here, we evaluate a dual-siRNA therapeutic strategy targeting this kinase pair and position it within a platform engineered for localized RNA delivery. Across three DPM subtypes (epithelioid, sarcomatoid, and biphasic), siRNA constructs achieved robust knockdown of WEE1 and PKMYT1, with >70% reduction in mRNA levels at 48-96 h post-transfection. Single-gene silencing induced only modest reductions in cell viability, with >70-80% survival across most lines relative to controls. In contrast, combined WEE1/PKMYT1 knockdown consistently elicited a marked decrease in viability, ranging from 60% to 85% depending on the cell line (p < 0.001). Cell-cycle analysis revealed that dual knockdown, unlike individual siRNAs, induced significant G2/M arrest accompanied by a depletion of S-phase cells, indicating disruption of DNA damage checkpoints. Flow cytometry demonstrated a 3- to 5-fold increase in apoptotic cell fractions compared with single knockdowns and controls (p < 0.0001), confirming synergistic induction of programmed cell death. These data show that although individual siRNAs exert limited effects, their combination produces robust anti-proliferative, pro-apoptotic, and cell-cycle disruptive phenotypes consistent with synthetic lethality. Collectively, these data validate dual-siRNA synthetic lethality as a promising therapeutic approach for DPM and underscore the potential of a nanoparticle-hydrogel delivery system that we have developed for precise, localized RNA therapy. This work paves the way for RNA nanomedicine in mesothelioma and other anatomically restricted, treatment-refractory cancers.", "source_company": "NCI\nNational Cancer Institute", "source_org_type": "研究机构", "row_number": 674, "target_meta": "WEE1,PKMYT1", "MOA_meta": "其他"}, {"drug_name": "anti-PD-1", "company": "Asan Medical Center", "org_type": "医院", "target": "PD-1", "modality": "inhibitor", "importance_level": "中", "total_score": 52.5, "institution_score": 35, "track_score": 75, "milestone_score": 55, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "anti-PD-1为经典免疫检查点抑制剂，靶点PD-1在免疫治疗领域热度高，但本研究由医院机构开展且主要为机制探索而非药物开发本体。Paclitaxel与anti-PD-1联合在HNSCC模型中显示协同抑瘤及重塑TME作用，preclinical证据较清晰但无药物自身新进展。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3658", "id": "o1XM_5wBX1NQZOEH-LO6", "source_drug_name": "anti-PD-1", "title": "Paclitaxel induces colocalization of CXCL9⁺ tumor-associated macrophages and CD8⁺ T cells to potentiate antitumor immunity in head and neck squamous cell carcinoma", "abstract_text": "Background: Paclitaxel is a key chemotherapeutic agent for head and neck squamous cell carcinoma (HNSCC). Recent studies have suggested the role of paclitaxel in immune responses, particularly relevant to tumor-associated macrophages (TAMs). This study explores the immunomodulatory role of paclitaxel in the tumor microenvironment (TME), focusing on its interaction with TAMs in HNSCC.\nMethods: In vitro and in vivo studies were conducted on murine samples and human samples from our tertiary referral center. The in vitro experiment involved murine bone marrow-derived macrophages (BMDMs) to evaluate phagocytic functions and the expression of MHC-related genes and proteins. Our in vivo study aimed to discriminate the spatial characteristics of SPP1+/CXCL9+ TAMs and their interaction with CD8+ T cells, especially under exposure to paclitaxel, using mouse oral carcinoma (MOC) and HNSCC samples.\nResults: Paclitaxel enhanced macrophage phagocytosis and upregulated antigen processing genes. In the murine HNSCC model, paclitaxel combined with anti-PD-1 significantly suppressed tumor growth, whereas either treatment alone was ineffective. This was associated with the redistribution of CXCL9+ TAMs into the tumor core. Consistently, human HNSCC samples demonstrated that paclitaxel-based neoadjuvant chemotherapy (NAC) was linked to improved survival and increased infiltration of CXCL9+ TAMs and CD8+ T cells into the tumor core, indicating a shift from an \"immune-excluded\" to an \"inflamed\" microenvironment.\nConclusion: Paclitaxel upregulates the phagocytic and antigen-presenting function of TAMs while spatially redistributing them toward the tumor core and subsequently inducing CD8+ T cell infiltration. Such features suggest that Paclitaxel may reprogram an immune-deserted TME to an anti-tumoral condition, ultimately contributing to immunotherapy responsiveness.", "source_company": "Asan Medical Center", "source_org_type": "医院", "row_number": 760, "target_meta": "PD1", "MOA_meta": "抑制剂"}, {"drug_name": "CD8a:MyD88 synthetic co-receptor expressing γδ T cells", "company": "Johns Hopkins University", "org_type": "大学", "target": "未披露", "modality": "CAR", "importance_level": "中", "total_score": 52.5, "institution_score": 35, "track_score": 85, "milestone_score": 45, "field_heat_score": 75, "bonus_score": 3, "brief_reason": "该产品为工程化表达CD8a:MyD88合成共受体的γδ T细胞，用于增强儿科肉瘤的过继细胞治疗活性，靶点未明确披露。大学机构早期探索性研究，赛道为热门的细胞治疗+新型工程化改造，整体处于preclinical阶段且仅显示初步体外改善，故综合重要性中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1780", "id": "wFXM_5wBX1NQZOEH-LO6", "source_drug_name": "CD8a:MyD88 synthetic co-receptor expressing γδ T cells", "title": "Using γδ T cells as a potent adoptive cell therapy platform in models of pediatric sarcoma", "abstract_text": "New treatment approaches for high-risk pediatric sarcomas are desperately needed. Immunotherapy advances with adoptive cell therapy in hematologic malignancies have not yet been translated to pediatric solid tumors including sarcomas. Hallmarks of the immune microenvironment in pediatric sarcomas include the presence of immunosuppressive immune cells and cytokines, and a lack of potent T cell activation. We are seeking ways to overcome these barriers to effective adoptive cell therapy in pediatric sarcomas. γδ T cells are known to have innate anti-tumor activity across many cancers but their activity against pediatric sarcomas remains poorly characterized. Here we detail the anti-tumor activity of γδ T cells against a panel of human and murine models of pediatric sarcomas including human and murine osteosarcoma (OS), human and murine rhabdomyosarcoma (RMS), and human Ewings sarcoma (EWS). Human and murine γδ T cells demonstrated varied anti-tumor activity across the different models of pediatric sarcomas. Co-cultures of varying effector to target ratios (E:T) of γδ T cells to tumor demonstrated strong anti-tumor effects against our models of OS and EWS. Interestingly, RMS, especially the human fusion-positive RMS cell line Rh30 showed significant resistance to γδ T cell killing. We further assessed the γδ T cell potency against pediatric sarcomas in vivo. In our syngeneic and human tumor xenograft models of sarcoma we observed temporary tumor growth control following adoptive transfer with ten million activated γδ T cells highlighting the need to improve in vivo function. We explored the addition of intratumoral STING (stimulator of interferon genes) agonist with the goal of increasing γδ T cell trafficking to the tumor. We show that STING agonist delivery prior to adoptive transfer results in increased numbers of γδ T cells in the tumor. In addition, we are exploring the introduction of a novel synthetic co-receptor, CD8a:MyD88, shown previously to augment αβ T cell effector function, to determine if γδ T cell function can be improved as well. We transduced γδ T cells ex vivo to express the CD8a:MyD88 synthetic co-receptor resulting in improved in vitro tumor lytic function and increased interferon gamma production when co-cultured with osteosarcoma cells compared to control vector-transduced T cells. Ongoing and future work is investigating the in vivo effectiveness of the CD8a:MyD88 expressing γδ T cells in our panel of sarcoma models. These studies further define the obstacles and potential solutions to successful adoptive T cell therapy for pediatric sarcomas.", "source_company": "Johns Hopkins University", "source_org_type": "大学", "row_number": 783, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "MALT1 inhibitor", "company": "Mayo Clinic", "org_type": "医院", "target": "MALT1", "modality": "inhibitor", "importance_level": "中", "total_score": 52.5, "institution_score": 35, "track_score": 75, "milestone_score": 55, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "MALT1作为PAR1下游效应器通过支架功能调控TNBC中PD-L1表达，促进免疫逃逸，靶向MALT1抑制剂有望联合ICI提升免疫治疗效果。Mayo Clinic为顶级医院研究机构而非商业公司导致机构分较低，但MALT1在肿瘤免疫调控中的机制新颖且临床开发已有抑制剂，赛道和潜力支撑中位重要性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/7403", "id": "ZZ7ECZ0BZznHJdntvNYd", "source_drug_name": "MALT1 inhibitor", "title": "A cancer cell-intrinsic PAR1/MALT1/PD-L1 signaling pathway drives immune evasion in triple-negative breast cancer", "abstract_text": "Background: Triple-negative breast cancer (TNBC) is the most aggressive subtype of breast cancer and remains difficult to treat due to the absence of targeted therapies. While recent advances in immunotherapy, particularly with immune checkpoint inhibitors (ICIs), have transformed the treatment landscape for many cancers, response rates to ICIs remain low for TNBC, largely due to tumor-intrinsic immune evasion mechanisms.\nObjective: We identify and characterize a novel immune evasion pathway in TNBC driven by deregulation of cancer cell-intrinsic protease-activated receptor 1 (PAR1), a thrombin receptor frequently upregulated in aggressive tumors.\nMethods and Results: Through integrative bioinformatic analyses, genetic perturbations, xenograft models (immunodeficient and immunocompetent), flow cytometry-based tumor immune profiling, and RNA-seq, we demonstrate that PAR1 activation enhances immune evasion in TNBC. Mechanistically, we show that the paracaspase MALT1 acts as a critical downstream effector of PAR1 signaling and promotes immune escape by driving PD-L1 expression in TNBC cells. Functional assays reveal that genetic depletion of MALT1 or PD-L1 increases TNBC cell susceptibility to T cell-mediated cytotoxicity in vitro and significantly suppresses tumor growth in vivo. Notably, through knock-in and rescue experiments using a catalytically inactive MALT1 mutant, we reveal that MALT1’s scaffolding - rather than protease - function is essential for PD-L1 regulation. Immune cell depletion assays further identify CD4+ T cells, CD8+ T cells, and natural killer (NK) cells as key mediators of the anti-tumor immune response suppressed by the PAR1-MALT1 axis. These findings are supported by human TNBC specimen analyses, where MALT1 expression inversely correlates with T cell activation and positively associates with PD-L1 in PAR1-high, but not PAR1-low, tumors.\nConclusion: Our study reveals immune evasion as a novel mechanism of PAR1-driven breast cancer pathogenesis, mediated by a PAR1/MALT1/PD-L1 signaling cascade. These findings bridge a critical gap by positioning MALT1 at the interface between tumor-intrinsic signaling and the immune microenvironment - two areas of CARMA-BCL10-MALT1 (CBM) complex research that have largely evolved in parallel over the years. Importantly, targeting MALT1 may enhance immunotherapy efficacy in TNBC. Given the availability of MALT1 inhibitors in clinical development, our work supports combining MALT1 inhibition with ICIs or other immune-oncology agents as a promising strategy to overcome immune resistance in TNBC.", "source_company": "Mayo Clinic", "source_org_type": "医院", "row_number": 792, "target_meta": "MALT1", "MOA_meta": "抑制剂"}, {"drug_name": "BioRNA-siPLXND1", "company": "UC Davis", "org_type": "大学", "target": "PLXND1", "modality": "siRNA", "importance_level": "中", "total_score": 52.5, "institution_score": 35, "track_score": 75, "milestone_score": 55, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "通过tRNA scaffold bioengineering的siRNA靶向PLXND1这一在去势抵抗性前列腺癌尤其是NEPC中驱动耐药和神经内分泌转化的新兴靶点。大学机构分数较低，但siRNA+新型递送平台针对“undruggable”靶点在耐药前列腺癌领域有一定赛道热度和未满足需求，preclinical阶段显示体外/类器官/体内分布潜力。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5555", "id": "y1XM_5wBX1NQZOEH-LO6", "source_drug_name": "BioRNA-siPLXND1", "title": "Targeting PLXND1 using RNA bioengineering technologies and customized lipid nanoparticles in advanced prostate cancer", "abstract_text": "Background: PLXND1 (Plexin D1) is a transmembrane receptor that plays critical roles in promoting neural lineage plasticity and driving resistance to enzalutamide therapy in prostate cancer. Despite its significance, PLXND1 has been considered \"undruggable.\" siRNA-based therapeutics offer a strategy to silence disease-driving genes like PLXND1 but face limitations, including instability, poor cellular uptake, and off-target effects.\nMethods: We employed an RNA bioengineering approach using a tRNA/pre-miRNA-mir-34a scaffold to stabilize and express siRNAs targeting PLXND1 (BioRNA-siPLXND1). BioRNA/PLXND1-siRNA expression plasmids were constructed via molecular cloning, and the resulting BioRNA was purified and analyzed for quality, yield, and endotoxin levels. We tested BioRNA-siPLXND1 function in vitro and formulated it into lipid nanoparticles (LNPs) using two lipid components: DOPE and DOTAP. The stability, transfection efficiency, and safety of each formulation were evaluated in vitro and in vivo using prostate cancer cell lines and neuroendocrine prostate cancer (NEPC) patient-derived xenograft (PDX) organoids.\nResults: BioRNA-siPLXND1 achieved high yield and purity with low endotoxin levels. It efficiently silenced PLXND1 at the mRNA and protein levels, significantly inhibiting cell proliferation, colony formation, and organoid growth in vitro. Among the LNP formulations, LNP-DOTAP demonstrated higher transfection efficiency but greater cytotoxicity in normal cells, whereas LNP-DOPE showed a favorable safety profile and effective delivery. LNP-DOPE-loaded BioRNA-siPLXND1 remained stable for at least 7 days in vitro and suppressed tumor growth in NEPC PDX organoids. In vivo, LNP-DOPE accumulated in tumors within 2 hours, persisted for up to 4 days, and was predominantly retained in tumor tissue by day 7.\nConclusions: Our study demonstrates the feasibility and therapeutic potential of a tRNA-based BioRNA platform for delivering PLXND1-targeting siRNAs in prostate cancer. LNP-DOPE serves as a safe and effective delivery system, offering a promising strategy for targeting \"undruggable\" oncogenes like PLXND1 in therapy-resistant prostate cancer.\nFinancial support: This work was supported in part by grants from NIH/NCI R37CA249108 (Liu), R01CA251253 (Liu), R21CA277171 (Liu), Department of Defense HT9425-23-1-0144 (Liu), HT9425-23-1-0325 (Liu), HT9425-23-1-0324 (Dall’Era), and UC Davis Comprehensive Cancer Center Support Grant (CCSG) awarded by the National Cancer Institute (NCI P30CA093373).", "source_company": "UC Davis", "source_org_type": "大学", "row_number": 794, "target_meta": "PLXND1", "MOA_meta": "其他"}, {"drug_name": "Locked Nucleic Acid-based inhibitor", "company": "UT Health Houston", "org_type": "医院", "target": "miR-155", "modality": "ASO", "importance_level": "中", "total_score": 52.5, "institution_score": 30, "track_score": 75, "milestone_score": 65, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "药物为靶向miR-155的LNA-based抑制剂（ASO类），通过阻断miR-155/MT1E-MT1F/铜稳态轴增强溶瘤HSV在胶质母细胞瘤中的疗效。机构为医院系统得分较低，但miR-155抑制+溶瘤病毒联合属于有机制创新的热门赛道，体外+原位模型显示显著增效，整体重要性中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/2347", "id": "Z57ECZ0BZznHJdntvNYd", "source_drug_name": "Locked Nucleic Acid-based inhibitor", "title": "Targeting microRNA-mediated copper homeostasis dysregulation to enhance intratumoral susceptibility to oncolytic herpes simplex virus-1 in glioblastoma", "abstract_text": "Glioblastoma (GBM) is a WHO grade IV astrocytoma characterized by diffuse infiltration, rapid proliferation, and resistance to conventional therapies, resulting in dismal patient outcomes. Oncolytic virotherapy, particularly utilizing genetically engineered oncolytic herpes simplex virus-1 (oHSV), has demonstrated tumor-selective cytolysis and immunogenic cell death. Despite promising preclinical data, clinical efficacy remains limited due to poorly defined intrinsic resistance mechanisms within the tumor microenvironment (TME) of GBM. Our study identified microRNA-155 (miR-155) as a critical modulator of oHSV therapeutic resistance. We found elevated miR-155 expression in GBM compared to low-grade gliomas, which correlates with a poor prognosis and reduced response to OV therapy. These findings were further supported by The Cancer Genome Atlas (TCGA) data. Ectopic overexpression of miR-155 significantly attenuated oHSV replication and cytopathic effects. Transcriptomic profiling and pathway enrichment analyses revealed that miR-155 upregulates metallothioneins MT1E and MT1F, key regulators of intracellular copper sequestration and antiviral defense. Mechanistically, miR-155 disrupts copper homeostasis via the MT1 axis, impairing viral replication and therapeutic efficacy. Functional ablation of miR-155 via CRISPR/Cas9-mediated knockout or Locked Nucleic Acid (LNA)-based inhibition restored copper homeostasis, oHSV replication kinetics, and enhanced oncolysis in vitro and in orthotopic GBM xenograft models, resulting in prolonged survival. These data suggest that the miR-155/MT1E-MT1F/copper signaling axis represents a novel barrier to oHSV therapy. This work elucidates a previously uncharacterized antiviral resistance pathway in GBM and validates miR-155 inhibition as a rational therapeutic strategy to potentiate oHSV efficacy. Our findings provide a mechanistic framework for overcoming innate resistance and advancing the clinical translation of virotherapy in neuro-oncology. This abstract was originally written by the authors and then edited and revised with generative artificial intelligence (AI).", "source_company": "UT Health Houston", "source_org_type": "医院", "row_number": 803, "target_meta": "miR-155", "MOA_meta": "反义疗法"}, {"drug_name": "co-hu-HSAN-PBD ADC", "company": "Children's Hospital of Philadelphia", "org_type": "医院", "target": "GFRA2", "modality": "ADC", "importance_level": "中", "total_score": 52.5, "institution_score": 35, "track_score": 75, "milestone_score": 55, "field_heat_score": 60, "bonus_score": 2, "brief_reason": "该ADC靶向GFRA2，在神经母细胞瘤和尤文肉瘤中高表达，显示出体外强效特异性杀伤（pM级IC50），但靶点非主流热门。机构为知名儿童医院而非头部药企，得分中等；ADC赛道热度较高，前临床数据初步有潜力但仍在优化阶段。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1774", "id": "5FXM_5wBX1NQZOEH-LO6", "source_drug_name": "co-hu-HSAN-PBD ADC", "title": "Development of a GFRA2-targeting antibody drug conjugate for neuroblastoma (NB), and Ewing sarcoma (EWS)", "abstract_text": "Background: We recently defined the NB/EWS surfaceomes using integrative proteogenomics to prioritize proteins as candidate immunotherapeutic targets. GFRA2 was a top ranked candidate for both NB and EWS (Clin Cancer Res 2023, Cancer Cell 2024).\nAims: (1) Validate and assess mechanism of GFRA2 overexpression; (2) Identify selective antibody binders to GFRA2; (3) Engineer antibody drug conjugates (ADCs) and test for internalization and potency.\nMethods: ChIP- and RNA-sequencing of NB and RNA-sequencing following siRNA depletion of EWSR1::FLI1 were used to evaluate mechanisms of GFRA2 overexpression. GFRA2 abundance and cellular localization was evaluated by flow cytometry and immunofluorescence. Phage display was performed with recombinant GFRA2 extracellular domain protein as the bait and the highly conserved GFRA1 and GFRA3 recombinant proteins as counters. In parallel, we humanized the anti-GFRA2 murine HSAN antibody. While we plan on reporting on several linker-payload combinations, here we focus on the initial humanized HSAN antibody conjugated to pyrrolobenzodiazepine (PBD) via a cleavable linker, which was tested for internalization using live cell imaging and cytotoxicity across a panel of human NB and EWS preclinical models.\nResults: We identified a proximal super enhancer (Percentile: 97.4%-99.7%) or enhancer (94.4%-97.7%) in all 10 NB cell lines profiled. Depletion of EWSR1::FLI1 resulted in significantly decreased GFRA2 mRNA expression across 6 EWS cell lines (P<0.0001), and this was validated via immunoblotting. GFRA2 protein was expressed uniformly and to variable degrees on the cell surface of 10 NB cell lines, 8 NB patient-derived xenografts, and 6 EWS cell lines by flow cytometry and/or immunofluorescence. Patient tumor RNA-Seq showed 92.8% of NB (N=126; median=47.65) and 74% of EWS (N=85, median=11.47) had high expression defined as a GFRA2 TPM > 5. Phage display panning of fully human antibody fragments yielded three Fabs and one VH single domain antibody specific to GFRA2 with moderate binding affinity (50-500 nM). Humanized HSAN (co-hu-HSAN) showed high binding affinity specific to GFRA2 (1-10 nM). We then showed robust internalization of co-hu-HSAN across 6 NB cell lines. A co-hu-HSAN-PBD ADC showed potent and specific cytotoxicity across GFRA2+ cell lines (NB=2; median IC50=1.69;2.92pM, EWS=2; median IC50=9.81;12.43pM) with no cytotoxicity in GFRA2 null cell lines (N=2; median IC50=NA).\nConclusions: GFRA2 is a lineage restricted oncoprotein abundantly expressed in both NB/EWS, as well as other human solid cancers. We show initial proof-of-concept for potent and specific cytotoxicity in both NB/EWS with the co-hu-HSAN-PBD ADC. We will report on efficacy testing of the co-hu-HSAN-PBD ADC across NB/EWS xenograft models. Work to affinity enhance the fully human binders, and progress with additional linker/payload combinations are ongoing and will be reported.", "source_company": "Children's Hospital of Philadelphia", "source_org_type": "医院", "row_number": 810, "target_meta": "GFRA2", "MOA_meta": "抗体偶联药物"}, {"drug_name": "MEK1/2 PROTACs", "company": "Fox Chase Cancer Center", "org_type": "医院", "target": "MEK1/2", "modality": "PROTAC", "importance_level": "中", "total_score": 52.5, "institution_score": 35, "track_score": 85, "milestone_score": 45, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "MEK1/2 PROTAC揭示了MEK1/2在CRAF稳定和成熟中的激酶非依赖作用，机制新颖。机构为医院/学术中心、仍处preclinical机制研究阶段导致总分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1860", "id": "-lXM_5wBX1NQZOEH-LO6", "source_drug_name": "MEK1/2 PROTACs", "title": "MEK1/2 degraders uncover kinase-independent role of MEK1/2 in CRAF stabilization and maturation", "abstract_text": "The mitogen-activated protein kinase (MAPK) cascade is an evolutionarily conserved signaling pathway comprised of RAS GTPases, and downstream effector kinases (RAF, MEK, and ERK) that promote cell growth and survival. MEK1 and MEK2 (MEK1/2) are ubiquitous members of the dual-specificity MAP2K kinase family that phosphorylate and activate ERK1/2, controlling cellular proliferation. MEK1/2 paralogs share highly similar kinase domains, including their activation loops, which are phosphorylated by the upstream RAF family of kinases ARAF, BRAF, and CRAF. The activation of MEK1/2 by RAF is thoroughly described; RAF directly interacts with and phosphorylates MEK1/2, resulting in MEK1/2 kinase activation and subsequent phosphorylation of ERK1/2. In contrast, how the upstream RAF kinase, particularly CRAF, is activated is highly complex, involving an orchestration of chaperones, phosphorylation, and RAF dimerization, ultimately resulting in the phosphorylation of MEK1/2. The recognized CRAF signaling cascade has MEK1/2 functioning solely as a substrate of CRAF, binding to CRAF after RAS binding and RAF dimerization. However, there is evidence that MEK1 can directly regulate CRAF activity independent of RAS, suggesting that MEK1 has additional functions in the CRAF cycle. Here, using MEK1/2 proteolysis targeting chimeras (PROTACs), we discovered that MEK1/2 have kinase-independent functions in the regulation of CRAF protein stabilization, maturation, and kinase activation. Our findings reshape the current view of the CRAF activation cycle, establishing MEK1/2 binding to CRAF as an early required stabilizing event preceding CRAF-RAS engagement. Thus, MEK1/2 functions as both an activator and substrate of CRAF.", "source_company": "Fox Chase Cancer Center", "source_org_type": "医院", "row_number": 825, "target_meta": "MEK1,MEK2", "MOA_meta": "PROTAC"}, {"drug_name": "GM2-specific monoclonal antibody", "company": "Dana-Farber Cancer Institute", "org_type": "医院", "target": "GM2", "modality": "monoclonal antibody", "importance_level": "中", "total_score": 52.5, "institution_score": 35, "track_score": 65, "milestone_score": 70, "field_heat_score": 60, "bonus_score": 4, "brief_reason": "靶向GM2的单抗，针对GD2治疗后耐药的神经母细胞瘤，通过补偿性GM2升高实现双靶点策略预防抗原逃逸。机构为顶级癌症研究医院但非药企导致机构分较低，赛道为儿科实体瘤免疫靶点+组合策略有一定热度，preclinical模型显示肿瘤根除和长期存活带来较强里程碑价值。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1746", "id": "GVXM_5wBX1NQZOEH-LS6", "source_drug_name": "GM2-specific monoclonal antibody", "title": "Ganglioside targeting: Exerting sweet revenge on neuroblastoma", "abstract_text": "Neuroblastoma (NBL) is the most common extracranial solid tumor diagnosed in children and is responsible for 11% of pediatric cancer deaths. Dinutuximab is an FDA approved monoclonal antibody (mAb) against GD2, used in the treatment of high-risk NBL. Despite integration of dinutuximab into upfront treatment protocols, 40-50% of patients still relapse and eventually die of their disease. Resistance to anti-GD2 therapy is poorly understood. Previously, we have shown GD2 loss in xenografts in response to anti-GD2 immunotherapy. This resistance mechanism is driven by downregulation of one enzyme, ST8SIA1 while other enzymes in the GD2 pathway remain unchanged. We hypothesized that loss of ST8SIA1 leads to reduced GD2 and a compensatory increase in GM2. In the present work, we validate our hypothesis, vetting GM2 as an immunotherapy target for which we engineered GM2-specific chimeric antigen receptors (CAR) and mAbs and tested their efficacy and safety in murine models.First, we tested anti-GM2 mAbs as a monotherapy in 3 metastatic NBL xenograft models. Regardless of initial efficacy, monotherapy fail to provide long-lasting responses and eventually all mice relapsed. However, because each antibody showed partial activity in the GD2-high model, we added a combination-therapy arm in the next experiment. The combination proved to be superior, as all mice receiving it saw tumor eradication and long-term survival.We then tested anti-GM2 CAR T cells, based on the same binder used for mAbs, and saw robust and durable responses. Dual targeting GD2 and GM2, with a tandem GM2-GD2 CAR, was able to eliminate the tumors completely and provided long-term survival.Ganglioside distribution in normal tissue is poorly understood. However, it is known that GD2 is present in peripheral nerves, where it causes neuropathic pain, the main dose-limiting toxicity. To anticipate potential toxicities the combination could present, we optimized ganglioside detection by IHC on frozen tissue and successfully screened healthy tissue microarrays (TMAs). GM2 showed limited tissue distribution, being restricted to the kidneys and thyroid. More importantly, no overlap between GD2 and GM2 was observed.We also screened murine tissues from in search of a safety model. The kidneys of C57Bl/6 mice showed GM2 levels comparable to human kidneys, so were used for toxicity studies. GM2 mAbs were well tolerated with no evidence of off-target toxicity, no weight loss or noticeable pathological features.Finally, courtesy of NANT, we procured viably frozen bone marrow samples from relapsed NBL patients, previously treated with anti-GD2. These samples showed heterogeneous GD2, yet high GM2.Together these data shows, GD2 loss driven by immunotherapy and a concomitant increase in GM2. More importantly, it validates GM2 as an alternative target for GD2 low NBL and because GM2 has limited normal-tissue expression, it can be safely targeted alongside GD2 to prevent antigen escape", "source_company": "Dana-Farber Cancer Institute", "source_org_type": "医院", "row_number": 848, "target_meta": "GM2", "MOA_meta": "单抗"}, {"drug_name": "rBCR Ab", "company": "UT MD Anderson Cancer Center", "org_type": "医院", "target": "未披露", "modality": "other", "importance_level": "中", "total_score": 52.5, "institution_score": 35, "track_score": 75, "milestone_score": 55, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "rBCR Ab为基于肿瘤浸润B细胞受体的重组抗体，靶点未明确披露；机构为顶级肿瘤医院但非药企，赛道为新型BCR抗体免疫治疗具创新性，处于早期功能验证+体内协同PD-1模型阶段。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9502", "id": "nFXM_5wBX1NQZOEH-LS6", "source_drug_name": "rBCR Ab", "title": "Harnessing tumor-informed B cell receptors for discovery and antibody-based immunotherapy in sarcoma", "abstract_text": "Background: Soft tissue sarcomas (STS) are rare and heterogenous cancers, with limited effective treatments and poor prognosis. While some patients with STS respond to immune checkpoint blockade (ICB), the majority do not benefit. This highlights an urgent need to elucidate mechanisms of response and resistance to ICB and develop novel immunotherapeutic approaches for patients with STS. We and others have shown that tumor infiltrating B cells (TIL-Bs), particularly those in tertiary lymphoid structures (TLS) are associated with response to ICB and longer survival. However, the antigen specificity, mechanisms of action, and therapeutic potential of these TIL-Bs and their B cell receptors (BCRs) remain unknown.\nMethods: We recently completed a phase 2 clinical trial evaluating ICB administered in the neoadjuvant setting in patients with resectable undifferentiated pleomorphic sarcoma (UPS) of the extremity/trunk or dedifferentiated liposarcoma (DDLPS) of the retroperitoneum (Roland et al. Nature Cancer 2024). Leveraging a unique biospecimen resource from this trial, we reconstructed intratumoral BCR heavy and light chain (VH and VL) repertoires using pre-treatment baseline tumor biopsies (n = 27), RNA-sequencing, and an in-house pipeline including TRUST4. We then performed single intratumoral B cell immunoglobulin sequencing using cell suspensions from 4 TLS-positive tumors to reconstruct and express 105 recombinant BCR antibodies (rBCR Abs) as IgG1. Flow cytometry (FC) was performed to characterize the binding features of a subset of 20 rBCR Abs with human DDLPS (LPS224, LPS246) and UPS cell lines (UPS186, RIS819.1). Binding was quantified as the ratio of the mean fluorescent intensity (MFI) of the antibody to the MFI of the isotype control for each cell line. Abs with an MFI ratio ≥ 1.2 were classified as binders and tumor surface binding was further assessed by live cell microscopy. Antibody-dependent cellular cytotoxicity (ADCC) assays were performed to assess the functional capacity of this cohort of rBCR Abs to mediate NK-cell dependent tumor killing. The anti-tumor efficacy of 1 lead rBCR Ab was assessed using an MCA205 immunocompetent murine STS model.\nResults: Of 105 rBCR Abs screened, 23 (22%) exhibited reproducible surface binding to at least one sarcoma cell line by FC. Among these, 13 (12%) bound LPS lines and 18 (17%) bound UPS lines. To date, 20 rBCR Abs have been confirmed to bind the surface of sarcoma cell lines by live cell staining of which 5 mediated tumor cell killing in vitro. One candidate rBCR Ab has been evaluated in vivo, localizing to tumor and synergized with PD-1/PD-L1 blockade to suppress tumor growth when administered intraperitoneally.\nConclusion: These findings highlight the potential of rBCR Abs to serve as a novel therapeutic strategy and as tools to elucidate the roles of B cells and the BCR repertoire within the tumor immune microenvironment of patients with STS.", "source_company": "UT MD Anderson Cancer Center", "source_org_type": "医院", "row_number": 944, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "anti-glypican-3 (GPC3) CAR T cells", "company": "The Chinese University of Hong Kong", "org_type": "大学", "target": "GPC3", "modality": "CAR", "importance_level": "中", "total_score": 52.5, "institution_score": 35, "track_score": 75, "milestone_score": 55, "field_heat_score": 65, "bonus_score": 3, "brief_reason": "靶向GPC3的CAR-T细胞，采用synNotch和SNIPR等合成基因电路实现肿瘤微环境特异性激活，显著降低脱靶毒性。大学机构分数较低，但CAR-T在实体瘤尤其是HCC的优化平台具有技术创新性，preclinical数据较扎实。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5201", "id": "dp7ECZ0BZznHJdntvNYd", "source_drug_name": "anti-glypican-3 (GPC3) CAR T cells", "title": "CAR-T cells with GPC3-inducible gene circuits for targeting hepatocellular carcinoma", "abstract_text": "Despite the remarkable success of chimeric antigen receptor (CAR) T-cell therapy in hematologic malignancies, its application to solid tumors such as hepatocellular carcinoma (HCC) remains limited by insufficient tumor-specific activation and systemic toxicity from constitutive immunostimulation. To overcome these challenges, we engineered anti-glypican-3 (GPC3) CAR T cells incorporating inducible gene circuits that enable spatially and temporally controlled activation within the tumor microenvironment. Utilizing a lentiviral delivery system, we generated GPC3-specific CAR T cells exhibiting potent antigen-dependent cytotoxicity against HepG2 cells in vitro and significant tumor regression in immunodeficient xenograft models. To achieve precise antigen-gated regulation, we implemented a synthetic Notch (synNotch) receptor system and systematically characterized its induction dynamics and kinetics using a Jurkat T-cell reporter platform. Through single-chain variable fragment (scFv) screening, we identified an optimized anti-GPC3 scFv that conferred high sensitivity and specificity for HCC-associated GPC3. Subsequent engineering refinements, including deletion of the negative regulatory region (NRR) and incorporation of a SyNthetic Intramembrane Proteolysis Receptor (SNIPR) architecture, substantially enhanced receptor responsiveness, yielding robust, GPC3-dependent transgene expression with minimal basal leakage. Functional validation in both two-dimensional co-cultures and three-dimensional tumor spheroids confirmed that the optimized anti-GPC3 SNIPR system drives potent, target antigen-restricted transgene activation exclusively upon engagement with GPC3-positive tumor cells. Collectively, these findings establish a modular and tunable platform for inducible CAR T-cell therapy in HCC, demonstrating that synthetic gene circuits can enforce stringent spatial control over T-cell activation in the anti-GPC3 context. This approach holds significant promise for improving the therapeutic index of CAR T-cell therapy in HCC by simultaneously enhancing antitumor efficacy and mitigating off-tumor toxicity.", "source_company": "The Chinese University of Hong Kong", "source_org_type": "大学", "row_number": 947, "target_meta": "GPC3", "MOA_meta": "其他"}, {"drug_name": "UIM inhibitor", "company": "Van Andel Institute", "org_type": "研究机构", "target": "DNMT1 UIM", "modality": "inhibitor", "importance_level": "中", "total_score": 52.5, "institution_score": 35, "track_score": 75, "milestone_score": 45, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "靶向DNMT1的UIM结构域通过别构抑制其催化活性，实现表观遗传调控，为下一代DNMT抑制剂提供新机制。机构为研究机构得分较低，但表观遗传热门赛道+潜在新机制加分，整体preclinical阶段里程碑初步。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/2091", "id": "U57M_5wBZznHJdnt_W3O", "source_drug_name": "UIM inhibitor", "title": "Targeting the ubiquitin reading function of DNMT1 as a next-generation approach for epigenetic cancer therapy", "abstract_text": "DNA methyltransferase 1 (DNMT1) is the key enzyme supporting the epigenetic inheritance of DNA methylation patterns during DNA replication, a process frequently dysregulated across nearly all human cancers. Abnormal DNA methylation patterning is an appreciated mechanism of tumor suppressor gene (TSGs) silencing and immune evasion, motivating the clinical development of DNA methyltransferase inhibitors (DNMTi’s). While nucleoside analog DNMTi’s are the most clinically advanced epigenetic cancer therapies, their utility has been limited due to pharmacokinetic barriers and adaptive resistance mechanisms. New approaches to inhibit abnormal DNA methylation patterning are therefore needed. Here, we define the DNMT1 ubiquitin interacting motifs (UIMs), which recognize UHRF1-dependent histone H3 mono-ubiquitination, as targetable domains to allosterically inhibit DNMT1 catalytic activity, and we identify a pharmacophore that can be used as a starting point for UIM inhibitor development. To characterize the functional significance of the DNMT1 UIMs, we developed a genetic complementation system in two human colon cancer cell lines to cover the loss of endogenous DNMT1 with wild-type or loss-of-function mutants with disrupted catalytic or UIM activities. Disruption of DNMT1 UIM function mirrored DNMT1 knockdown, catalytic-dead mutant cover, and exposure to nucleoside- and non-nucleoside catalytic DNMT inhibitors. These effects included widespread DNA hypomethylation that correlated with the re-expression of epigenetically silenced TSGs and transposable elements, reduced colony formation, impaired cell proliferation, and impaired growth of xenografted tumors. A pilot screen of a chemical library revealed four compounds with a shared pharmacophore able to disrupt the interaction of DNMT1 with ubiquitinated nucleosomes. Collectively, these studies demonstrate that the oncogenic properties of DNMT1 are supported by its ubiquitin reading function and provide a roadmap for developing next-generation DNMT1 inhibitors targeting this allosteric site.", "source_company": "Van Andel Institute", "source_org_type": "研究机构", "row_number": 1006, "target_meta": "DNMT1", "MOA_meta": "抑制剂"}, {"drug_name": "AURKA inhibitor", "company": "Baylor College of Medicine", "org_type": "大学", "target": "AURKA", "modality": "inhibitor", "importance_level": "中", "total_score": 52.5, "institution_score": 35, "track_score": 75, "milestone_score": 45, "field_heat_score": 65, "bonus_score": 3, "brief_reason": "药物为AURKA抑制剂，靶向AURKA激酶以利用NSD1/SETD2双失活导致的ccRCC有丝分裂脆弱性。机构为大学得低分，赛道AURKA抑制在特定遗传背景RCC有一定新机制潜力但非最热门，停留在机制研究阶段得中低里程碑分，总分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3492", "id": "YJ7M_5wBZznHJdnt_W3O", "source_drug_name": "AURKA inhibitor", "title": "NSD1-AURKA-SETD2 axis creates novel mitotic vulnerabilities in clear cell renal cell carcinoma", "abstract_text": "Background: Chromothripsis-driven 3p deletion and 5q amplification are early, clonal events in clear cell renal cell carcinoma (ccRCC). These lesions respectively target the epigenetic regulators SETD2 and NSD1. Paradoxically, although NSD1 is amplified on 5q, it is frequently hypermethylated and transcriptionally silenced, suggesting functional inactivation is selected for. The mechanistic implications of NSD1 and SETD2 loss in mitotic control remain poorly understood.\nMethods: We integrated multi-pronged approaches using in vitro kinase and methyltransferase assays, mass spectrometry, molecular modeling, and CRISPR-engineered models to dissect the regulatory relationship between NSD1, AURKA, and SETD2. Protein-protein interactions and post-translational modifications were characterized via co-immunoprecipitation, immunoblotting, fluorescence microscopy, and quantitative proteomics.\nResults: We identified NSD1 as a methyltransferase that directly methylates AURKA, serving as a negative regulator of its kinase activity and subcellular dynamics during mitosis. Loss of NSD1, through genetic deletion or pharmacologic inhibition, led to AURKA hyperactivation, defective spindle architecture, chromosome mis-segregation, and increased micronuclei formation. Unexpectedly, we found that AURKA phosphorylates SETD2, functionally linking these two epigenetic regulators. This phosphorylation selectively regulated SETD2’s cytoskeletal activity without affecting its chromatin-associated roles. Disruption of this modification—via AURKA inhibition or mutation of the phosphorylation site—compromised mitotic fidelity and enhanced genomic instability.\nConclusions: Our findings reveal a novel regulatory pathway in which NSD1-mediated methylation suppresses AURKA, while AURKA phosphorylation regulates SETD2 activity on the cytoskeleton, linking these two tumor suppressors altered in renal cell carcinoma (RCC). Disruption of this NSD1-AURKA-SETD2 axis creates a state of mitotic vulnerability, opening the door for therapeutic intervention using AURKA inhibitors in genetically defined subsets of ccRCC. Our data present a rationale for loss of NSD1 and SETD2 in the setting of RCC aimed at dismantling this regulatory axis to drive tumor evolution. This dual loss creates a state of dependency on AURKA activity, providing a rationale for AURKA-based inhibition in a subset of RCC patients with dual loss of NSD1 and SETD2.", "source_company": "Baylor College of Medicine", "source_org_type": "大学", "row_number": 1014, "target_meta": "AURKA", "MOA_meta": "抑制剂"}, {"drug_name": "bispecific antibody (CHI3L1xPD-1)", "company": "Legoretta Cancer Center at Brown University", "org_type": "研究机构", "target": "CHI3L1 和 PD-1", "modality": "bispecific antibody", "importance_level": "中", "total_score": 52.5, "institution_score": 35, "track_score": 85, "milestone_score": 40, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "双特异性抗体同时靶向CHI3L1和PD-1，通过阻断Hippo-YAP/TAZ通路介导的PD-1/PD-L1轴来克服EGFR突变NSCLC的TKI耐药和免疫耐受。机构为大学癌症中心非头部公司导致机构分较低，但双抗+热门靶点/耐药机制赛道热度高，preclinical机制研究清晰但无强动物疗效数据。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4940", "id": "mZ7M_5wBZznHJdnt_W3O", "source_drug_name": "bispecific antibody (CHI3L1xPD-1)", "title": "Simultaneous targeting of CHI3L1 and PD-1/PD-L1 axis to overcome drug resistance and immune tolerance of EGFR non-small cell lung cancer", "abstract_text": "Background: Lung cancer is the leading cause of cancer deaths worldwide. Non-small cell lung cancer(NSCLC) accounts for 85% of all lung cancers. The overall prevalence rate of NSCLC with epidermalgrowth factor receptor (EGFR) mutations are significantly increasing in US. Oncogenic EGFR is atransmembrane protein which gets auto-phosphorylated to cause EGFR mutations (L858R, T790M, exon-19-deletion) in exon 18-21. Tyrosine kinase inhibitors (TKIs) are effectively targeted to treat mutated EGFRlung cancer. These TKIs showed favorable responses on patient’s treatments for 9-18 months but duringthe treatment, patients acquired EGFR mutations which results into the TKIs drug resistance and at thatpoint TKIs stops its efficacy for further treatment. Thus, there is a high medical unmet need for a newtherapeutic strategy to overcome drug resistance in patients with EGFR mutations. CHI3L1 expressed bymacrophages, neutrophils, epithelial cells, smooth muscle cells, chondrocytes including other immune cells.The levels of circulating CHI3L1 are increased in many malignancies including cancers of the prostate,colon, rectum, ovary, kidney, breast, glioblastomas, malignant melanoma, and lung cancer. CHI3L1contributes to pulmonary metastasis and spread via the regulation of immune-checkpoint (ICP) molecules.Our studies showed that CHI3L1 regulates and is a potent stimulator of PD-1/PD-L1 and PD-L2. CHI3L1stimulates the EGFR physiologic ligands EGF or TGF-a, a well-defined growth factors that stimulate EGFRphosphorylation. EGFR-YAP/TAZ signaling plays a growth-promoting role in cancers harboring EGFRalterations, and that inhibition of YAP/TAZ in combination with EGFR might be beneficial to prevent TKIdrug resistance and cancer recurrence.\nMethods: We analyzed EGFR mutant and resistant cells using techniques qPCR, protein accumulation,immuno-pull-down assay, immunofluorescence, FACS and therapeutic effect of YAP inhibitors in-vitroand in-vivo.\nResults: We identified that CHI3L1 augments YAP/TAZ nuclear translocation in EGFR mutant and TKIresistant cells. Also, YAP/TAZ inhibitors and agonists (Verteporfin, K-975) able to block YAP/TAZactivation and that suppress PD-1/PD-L1 in EGFR mutant and TKI resistant cells.\nConclusion: These findings led us to understand that CHI3L1 and PD-1/PD-L1 axis mediated throughactivation of Hippo-YAP/TAZ signaling pathways play an essential role in TKIs drug resistance andimmune tolerance that enhances the progression of EGFR NSCLC. Additionally, simultaneous targeting ofCHI3L1 and PD-1/PD-L1 axis employing bispecific antibody (CHI3L1xPD-1) may provide a bettertherapeutic option to overcome TKI resistance and immune tolerance of EGFR NSCLC.", "source_company": "Legoretta Cancer Center at Brown University\nLegorreta Cancer Center at Brown University", "source_org_type": "研究机构\n医院", "row_number": 1054, "target_meta": "CHI3L1,PD1", "MOA_meta": "双特异性抗体"}, {"drug_name": "β-lactams", "company": "The University of Texas Rio Grande Valley", "org_type": "大学", "target": "KRAS", "modality": "inhibitor", "importance_level": "中", "total_score": 52.5, "institution_score": 35, "track_score": 85, "milestone_score": 45, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "新型化学修饰的β-内酰胺作为KRAS抑制剂，在胰腺癌细胞系中体外活性显著优于吉西他滨且选择性较高。机构为大学、仍处早期合成与体外阶段导致总体评分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6543", "id": "4p7M_5wBZznHJdnt_W3O", "source_drug_name": "β-lactams", "title": "Beta-lactams, structural mimics of natural products, as anti-pancreatic cancer agents: A pilot study", "abstract_text": "Around 95% of pancreatic tumors harbor mutations in codons G12, G13, and Q61 of the KRAS gene. Thus, there is a significant unmet need for the development of selective KRAS inhibitors. Alternatively, the four-membered cyclic amides, commonly known as β-lactams, are found in nature. Since their discovery, beta-lactam antibiotics have played a central role in fighting against bacterial infections. However, the ‘upgradation’ of β-lactams from one generation to another is required for drug resistance, which is predominantly due to bacterially produced β-lactamase enzymes that hydrolyze the highly strained β-lactam ring because of tremendous angular strain. We hypothesize that, as cancer cells do not produce β-lactamase enzymes, the β-lactam ring’s stability should be higher in tumor environments. With appropriate chemical modifications, β-lactams should inhibit proteins responsible for the proliferation, angiogenesis, and metastasis of various cancers, including hepatobiliary-pancreatic carcinomas (HPCs). HPCs include hepatocellular carcinoma (HCC), biliary tract cancers (BTCs), and pancreatic cancer (PanCa), which are highly challenging to treat and manage. As a part of our ongoing research in developing small molecule inhibitors from natural sources through chemical modifications (semi-synthetic) and/or by appropriate structure-based design and synthesis of structural mimics of natural products, we have successfully carried out computer-assisted design, multi-step synthesis, and in vitro anti-pancreatic cancer evaluation of a small series of β-lactams as KRAS inhibitors. There are a few methods for synthesizing the beta-lactam core unit, and we used the [2+2] ketene-imine cycloaddition (Staudinger) reaction followed by derivatization to synthesize the target 2-azetidinones. Further, MTT and apoptosis assays, cell cycle analysis, gamma-H2AX (phospho-Ser139) staining, and BrdU incorporation studies were conducted. Most of the products in this series demonstrated excellent (in vitro) activity in pancreatic cancer cell lines. The newly synthesized β-lactams demonstrated hundreds- to thousands-fold higher activity than the positive control, gemcitabine, in PANC-1 cells. Comparison of IC50 values in pancreatic cancer cells (PANC-1) and normal pancreatic epithelial cells (NPC) shows that almost all compounds exhibit 3-359 times greater selectivity for PANC-1 than for NPC. The in silico, and in vitro validated β-lactams could successfully serve as an entry point for clinical trials after appropriate in vivo evaluation. The work will significantly strengthen the fight against pancreatic cancer and undoubtedly foster a collaborative environment for future research.", "source_company": "The University of Texas Rio Grande Valley", "source_org_type": "大学", "row_number": 1110, "target_meta": "KRAS", "MOA_meta": "抑制剂"}, {"drug_name": "a first-in-class TAU-1-directed androgen receptor (AR) and AR-V7 degrader", "company": "Weill Cornell Medicine", "org_type": "大学", "target": "AR and AR-V7", "modality": "molecular glue degrader", "importance_level": "中", "total_score": 52.5, "institution_score": 40, "track_score": 85, "milestone_score": 30, "field_heat_score": 70, "bonus_score": 5, "brief_reason": "该药物为靶向AR N端TAU-1区域的首创分子胶降解剂，同时降解AR和AR-V7，有望克服前列腺癌去势抵抗；机构为大学学术型，得分较低，但PROTAC/分子胶降解热门赛道及去势抵抗前列腺癌未满足需求带来较高赛道与领域热度，摘要禁运导致开发阶段信息缺失，里程碑评分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11453", "id": "FZ7M_5wBZznHJdnt_W7O", "source_drug_name": "a first-in-class TAU-1-directed androgen receptor (AR) and AR-V7 degrader", "title": "A first-in-class TAU-1-directed androgen receptor (AR) and AR-V7 degrader recruits DDB1-CUL4-RBX1 E3 ligase to eliminate AR signaling in lethal prostate cancer", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Weill Cornell Medicine", "source_org_type": "大学", "row_number": 1142, "target_meta": "AR-v7", "MOA_meta": "降解剂"}, {"drug_name": "senescent whole-tumor cells (SWCs) vaccine", "company": "The Ohio State University", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "中", "total_score": 52.5, "institution_score": 35, "track_score": 75, "milestone_score": 45, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "该疫苗基于条件重编程的原代肿瘤细胞诱导衰老后制备的全肿瘤细胞疫苗，机制为多抗原聚免疫原性，诱导强T细胞免疫并克服ICI耐药，但靶点未具体披露。机构为大学非商业实体得分较低，赛道为个性化肿瘤疫苗结合衰老免疫原性较热，处于preclinical早期有初步体内免疫激活数据但无肿瘤疗效结果，整体潜力中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9685", "id": "J57M_5wBZznHJdnt_W7O", "source_drug_name": "senescent whole-tumor cells (SWCs) vaccine", "title": "A senescent whole-cell vaccine platform derived from conditionally reprogrammed primary tumor cells primes potent T-cell immunity and overcomes ICI resistance in murine breast cancer models", "abstract_text": "Background: Aggressive cancers, including breast cancer, face challenges of therapeutic resistance and recurrence. Autologous cancer vaccines are limited by difficulties in obtaining sufficient primary tumor material. Our lab uses the Conditional Reprogramming Cell (CRC) method to enable long-term in vitro expansion of primary tumor cells. We are developing a novel vaccine strategy based on cellular senescence, a highly immunogenic state. We hypothesize that irradiated, senescent whole-tumor cells (SWCs) generated via CRC will function as potent, poly-antigenic vaccines to prime robust anti-tumor T-cell responses, synergize with immune checkpoint inhibitors (ICIs), and establish long-term immune memory.\nExperimental method: Senescence was induced in murine breast cancer lines by γ-irradiation. Immune priming was assessed by injecting SWCs into naïve syngeneic mice, quantifying systemic T-cell activation (CD4⁺, CD8⁺, CD69⁺, PD-1⁺) in spleens and lymph nodes via flow cytometry. Therapeutic efficacy will be evaluated in orthotopic, tumor-bearing mice treated with SWC vaccine + CpG adjuvant, +/- dual ICI blockade (anti-PD-L1/anti-CTLA-4). Endpoints include tumor regression and survival. Vaccine efficacy will also be tested in prophylactic and post-surgical anti-recurrence models (simulating R1/R2 residual disease).\nSummary of new data: In vivo immune-priming experiments (four weekly injections) demonstrated that senescent tumor cells elicited a robust, systemic adaptive immune response. Compared to controls, SWC-treated mice showed a marked expansion of both CD8α⁺ and CD4⁺ T-cell populations in spleens and lymph nodes. Flow cytometry revealed an activated effector phenotype with elevated CD69 and cytotoxic markers in CD8⁺ T cells. These findings confirm SWCs are highly immunogenic and induce systemic T-cell activation.\nConclusion: Senescent whole-tumor cells derived via the CRC method are a feasible and potent poly-antigenic vaccine platform. Our preliminary data demonstrate that this strategy breaks immune tolerance, inducing robust T-cell activation. This provides a strong rationale for advancing this personalized, autologous vaccine to overcome immune resistance and prevent recurrence in aggressive solid tumors.", "source_company": "Ohio State University\nThe Ohio State University", "source_org_type": "大学", "row_number": 1150, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "Dsup mRNA", "company": "University of Iowa", "org_type": "大学", "target": "未披露", "modality": "mRNA", "importance_level": "中", "total_score": 52.5, "institution_score": 35, "track_score": 75, "milestone_score": 55, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "Dsup mRNA通过保护DNA免受ROS损伤减轻博来霉素诱导的肺上皮毒性，属于mRNA递送用于保护性治疗的新应用；大学机构基础研究阶段得分为主，但mRNA+LNP+雾化递送至气道上皮的preclinical数据较为扎实，具有一定转化潜力。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6389", "id": "ZZ7M_5wBZznHJdnt_W7P", "source_drug_name": "Dsup mRNA", "title": "Tardigrade Dsup mRNA nanoparticles reduce chemotherapy-induced normal tissue toxicity", "abstract_text": "Bleomycin is a commonly used chemotherapeutic in the treatment of lymphomas and germ-cell tumors, yet its utility can be restricted by dose-limiting pulmonary toxicity. Bleomycin-induced generation of reactive oxygen species (ROS) causes significant damage to the alveolar epithelium. This leads to alveolar cell death, senescence, and maladaptive crosstalk with stromal cells, ultimately driving irreversible pulmonary fibrosis. Despite the clinical need, no approved strategy directly protects the lung epithelium from bleomycin toxicity. Certain natural organisms, namely tardigrades, can tolerate high levels of ROS-driven cellular damage. This tolerance is partially attributed to the tardigrade-specific Damage suppressor (Dsup) protein which interacts with chromatin and shields DNA from ROS. Our laboratory has recently shown that Dsup expression can protect other types of epithelia from radiation-induced injury. Because bleomycin and radiation share a common cytotoxic mechanism, we believe that Dsup could similarly protect alveolar epithelium. To this end, we developed a KC2/cholesterol/PEG/DOPE lipid nanoparticle (LNP) formulation optimized for Dsup mRNA delivery to human airway epithelium. This formulation was optimized to achieve >95% transfection efficiency in human small airway epithelial cells (HSAECs) and A549 cells with minimal impact on viability or clonogenicity. Transient Dsup expression significantly attenuated bleomycin-induced DNA damage in A549 and HSAECs, reducing γ-H2AX foci by ~50% and decreasing alkaline comet % tail DNA by ~25% relative to controls. Dsup expression also mitigated epithelial cell senescence (detected via β-galactosidase assay) after bleomycin treatment. In A549 and HSAECs, β-gal-positive cells were reduced by ~40% at 16 days post-bleomycin treatment. To support translational feasibility, we evaluated the compatibility of our LNP formulation with nebulization and demonstrated that the LNPs retained particle size, polydispersity, and transfection efficiency after nebulization. We further assessed delivery in physiologically relevant models that typically resist nonviral mRNA transfection. In human and pig airway air-liquid-interface (ALI) cultures, multiple LNP formulations generated robust reporter (luciferase) expression. Additionally, dilution of LNPs in 4.5% NaCl further enhanced reporter expression by ~100-fold in our ALI models compared with isotonic conditions, highlighting an additional strategy to improve airway transfection. Collectively, these data demonstrate that Dsup expression substantially reduces bleomycin-induced DNA damage and senescence in airway epithelial cells and establishes that our LNP formulation can effectively deliver mRNA to human airway epithelium in vitro. This work provides a mechanistic foundation for the development of a novel approach for preventing bleomycin-induced pulmonary fibrosis.", "source_company": "University of Iowa", "source_org_type": "大学", "row_number": 1190, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "KLH-AM mRNA vaccine", "company": "Center for Biomedical Research of La Rioja (CIBIR)", "org_type": "研究机构", "target": "adrenomedullin (AM)", "modality": "mRNA", "importance_level": "中", "total_score": 52.5, "institution_score": 35, "track_score": 75, "milestone_score": 55, "field_heat_score": 65, "bonus_score": 3, "brief_reason": "药物为靶向促血管生成因子adrenomedullin (AM)的mRNA疫苗，通过诱导免疫应答抑制肿瘤血管生成和生长。机构为西班牙区域研究机构非头部药企，得分较低；mRNA+血管生成靶向机制在preclinical显示显著抗瘤效果且无明显毒性，具有一定创新性，但整体仍处早期阶段。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1519", "id": "cp7M_5wBZznHJdnt_W7P", "source_drug_name": "KLH-AM mRNA vaccine", "title": "An mRNA vaccine targeting angiogenesis elicits a robust immune response and inhibits tumor growth and angiogenesis in two mouse melanoma models", "abstract_text": "Background: Angiogenesis is essential for tumor growth, metastasis, and the establishment of an immunosuppressive microenvironment. By supporting nutrient delivery and modulating immune cell infiltration, tumor-driven angiogenesis promotes both malignant progression and immune evasion. Among its key regulators, adrenomedullin (AM) is a potent pro-angiogenic factor frequently overexpressed in solid tumors. To explore its therapeutic potential, we developed an mRNA vaccine encoding a fusion antigen composed of a small keyhole limpet hemocyanin (KLH) peptide, as a hapten, linked to mouse AM.\nMethods: The in vitro transcribed mRNA was encapsulated in lipid nanoparticles (LNPs) and administered to C57BL/6 mice, with empty LNPs serving as controls. The vaccine was evaluated in two distinct melanoma models: an experimental lung metastasis model induced by intravenous injection of B16-F10 melanoma cells, and a subcutaneous melanoma model. After four immunizations, melanoma cells were injected, followed by a fifth immunization. Mice were sacrificed once tumors reached humane endpoints and blood and organs were analyzed.\nResults: Vaccinated mice exhibited significant increases in anti-AM IgG titers (p= 0.040) and CD8+ T cell numbers (p=0.033) compared to controls. In the lung metastasis model, immunization resulted in a significant reduction in both the number (p=0.028) and size of lung metastases (p=0.020) as well as a decrease in the number of tumor-associated blood vessels (p=0.046), without disrupting normal vasculature as assessed in SMAA-GFP transgenic mice. In the subcutaneous model, vaccination delayed tumor initiation (p=0.005) and reduced tumor volume (p=0.004), accompanied by decreased tumor angiogenesis (p=0.045). Importantly, no systemic toxicity or significant changes in weight were observed.\nConclusion: By targeting angiogenesis, the KLH-AM mRNA vaccine effectively impaired tumor growth in melanoma models. These results highlight AM as an important pro-angiogenic factor driving tumor vascularization and support further development of AM-directed mRNA therapeutic vaccination as a strategy to disrupt angiogenesis-dependent tumor progression.This study was funded by Agencia Estatal de Investigación (AEI, Spain)’s project PID2022-136735OB-I00.", "source_company": "Center for Biomedical Research of La Rioja (CIBIR)", "source_org_type": "研究机构", "row_number": 1198, "target_meta": "ADM", "MOA_meta": "其他"}, {"drug_name": "YS-HepIII", "company": "Beckman Research Institute of The City of Hope", "org_type": "研究机构", "target": "heparan sulfate proteoglycans (HSPG)", "modality": "other", "importance_level": "中", "total_score": 52.5, "institution_score": 45, "track_score": 65, "milestone_score": 45, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "YS-HepIII利用工程化减毒沙门氏菌表达细菌HepIII酶靶向切割HSPG，阻断胰腺癌促瘤信号并增敏现有疗法。该项目来自知名研究机构City of Hope，preclinical阶段显示机制创新和潜在转化价值，但非热门modality和靶点导致赛道热度中等，总分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4381", "id": "h57M_5wBZznHJdnt_W7P", "source_drug_name": "YS-HepIII", "title": "Targeting heparan sulfate proteoglycans in pancreatic cancer with Salmonella expressing bacterial heparinase III", "abstract_text": "Heparan sulfate proteoglycans (HSPG) regulate processes that drive tumor progression and promote treatment resistance in pancreatic ductal adenocarcinoma (PDAC), including increased fatty acid metabolism, sustained survival signaling, high fibrosis, and increased macropinocytosis. HSPG are regulated in a pro-tumor manner by site-specific cleavage of their heparan sulfate chains by mammalian heparanase; however, alternative cleavage by bacterial heparinase III (HepIII) has been shown to deactivate these proteins and prevent downstream pro-tumor signaling. To broadly target HSPG on tumor cells surfaces, we have expressed a highly active bacterial HepIII from Bacteroides on a clinically evaluated, attenuated strain of Salmonella typhimurium, YS1646 (YS-HepIII). This tumor-targeting YS both continuously expresses active HepIII enzyme and limits its expression to tumor tissue using an inducible system to circumvent toxicities that might arise from systemic HepIII treatment. Analysis of human PDAC cell lines treated with YS-HepIII in vitro as well as of human PDAC xenograft tumors treated in vivo shows evidence of decreased macropinocytosis, reduced survival signaling, lipid storage depletion, and decreased expression of translation machinery. These vulnerabilities sensitize tumors to FDA approved cancer therapies. This translatable therapeutic has the potential to improve PDAC patient survival, an unmet medical need.", "source_company": "Beckman Research Institute of The City of Hope", "source_org_type": "研究机构", "row_number": 1215, "target_meta": "HSPG", "MOA_meta": "其他"}, {"drug_name": "personalized neoantigen vaccine", "company": "Dana-Farber Cancer Institute", "org_type": "医院", "target": "neoantigen", "modality": "vaccine", "importance_level": "中", "total_score": 52, "institution_score": 45, "track_score": 85, "milestone_score": 30, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "个性化neoantigen疫苗针对肿瘤特异性新抗原，机制为重编程胶质母细胞瘤免疫微环境，但摘要无具体内容。机构为知名癌症研究医院但非药企、开发阶段信息缺失导致总分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/210", "id": "51XM_5wBX1NQZOEH-LG6", "source_drug_name": "personalized neoantigen vaccine", "title": "A personalized neoantigen vaccine reprograms the immune landscape of glioblastoma", "abstract_text": "There is no abstract associated with this presentation.", "source_company": "Dana-Farber Cancer Institute", "source_org_type": "医院", "row_number": 21, "target_meta": "not available", "MOA_meta": "疫苗"}, {"drug_name": "COH005", "company": "Beckman Research Institute of The City of Hope", "org_type": "研究机构", "target": "PCNA", "modality": "inhibitor", "importance_level": "中", "total_score": 52, "institution_score": 45, "track_score": 75, "milestone_score": 35, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "COH005为新型小分子PCNA抑制剂支架，通过结合PIP-box口袋干扰PCNA介导的蛋白相互作用，类似已进入I期临床的AOH1996但处于早期发现阶段。机构为知名癌症研究机构但非头部药企，赛道因PCNA为历史性难成药靶点且有临床先例具备一定热度，preclinical结构验证+细胞验证但无体内数据或明确里程碑致总分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6420", "id": "_1XM_5wBX1NQZOEH-LK6", "source_drug_name": "COH005", "title": "Identification and structural characterization of a novel PCNA-interacting small molecule scaffold", "abstract_text": "Proliferating cell nuclear antigen (PCNA) plays essential roles in DNA replication, repair, transcription, and cell-cycle regulation, making it an attractive yet historically difficult target in cancer therapy. Building on our development of AOH1996, a first-in-class small molecule currently in Phase I clinical evaluation for solid and liquid tumors, we sought to identify additional PCNA-interacting chemotypes that could expand therapeutic opportunities and inform next-generation inhibitor design. Using an artificial intelligence-guided computer-aided drug discovery workflow, we screened more than ten million drug-like compounds and prioritized candidates through differential scanning fluorimetry. This approach led to the identification of COH005, a previously unreported small-molecule scaffold that binds PCNA. X-ray crystallography demonstrated that COH005 engages the major PCNA-interacting-protein (PIP)-box binding pocket, a critical interface for PCNA-mediated protein-protein interactions. Cellular thermal shift assays (CETSA) validated direct COH005-PCNA engagement in cells similar to clinical IND, AOH1996. To assess selectivity, we performed protein-structure frustration analysis comparing COH005 interactions with PCNA against an unrelated anti-target, revealing energetically favorable binding unique to PCNA. Together, these studies establish COH005 as a novel PCNA-interacting scaffold with strong potential for therapeutic development. This work provides a structural and mechanistic foundation for designing next-generation PCNA-targeted agents with improved specificity and pharmacological properties.", "source_company": "Beckman Research Institute of The City of Hope\nBeckman Research Institute at the City of Hope\nBeckman Research Institute of the City of Hope", "source_org_type": "研究机构", "row_number": 228, "target_meta": "PCNA", "MOA_meta": "抑制剂"}, {"drug_name": "5-ethynyl-2'-deoxyuridine", "company": "University of North Carolina at Chapel Hill", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "中", "total_score": 52, "institution_score": 35, "track_score": 45, "milestone_score": 75, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "EdU为胸苷类似物，通过核苷酸切除修复（NER）途径发挥作用，与TMZ形成DNA修复途径互补协同，但靶点机制未明确披露。大学机构非商业化主体得分较低，但动物模型中显著生存获益（部分小鼠长期存活无瘤）及患者来源组织协同证据显示较强临床转化潜力。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8787", "id": "EVXM_5wBX1NQZOEH-LG5", "source_drug_name": "5-ethynyl-2'-deoxyuridine", "title": "Combinatorial treatment of glioblastoma with temozolomide (TMZ) plus 5-ethynyl-2'-deoxyuridine (EdU)", "abstract_text": "Background: Glioblastoma (GBM) remains highly lethal despite surgery, radiotherapy, and temozolomide (TMZ). We identified a therapeutic role for 5-ethynyl-2′-deoxyuridine (EdU), a thymidine analog whose incorporation is recognized and excised by nucleotide excision repair (NER). We hypothesized that combining TMZ (lesions processed by mismatch repair and base excision repair) with EdU (NER-triggered) would overload complementary DNA repair pathways and improve efficacy.\nMethods: We tested TMZ+EdU across GBM cell lines (U87, GBM8), orthotopic mouse models (U87, GBM8), and living, passage-zero GBM patient tumor tissues on organotypic brain slice culture (OBSC). Viability was quantified by bioluminescence imaging; synergy via CompuSyn (cells) and ZIP scores (patient tissues). Short-course EdU dosing followed by histology assessed targeted localization of EdU to tumor cells.\nResults: In vitro, TMZ+EdU produced strong synergy in U87 and GBM8 across TMZ doses. In mice bearing U87 orthotopic xenografts, median survivals, reported in days (d), were 29 d (PBS), 37 d with 200 mg/kg EdU (+~30% vs PBS, p<0.001), 43 d with 5 mg/kg TMZ (+~50% vs PBS, p<0.001), and 67 d with 5 mg/kg TMZ + 200 mg/kg EdU (+~131% vs PBS, p<0.001). Notably, the combination yielded a +~60-80% improvement over monotherapies (p<0.001). Approximately 13% of combination-treated mice survived to the study endpoint with no detectable tumor. In mice bearing orthotopic GBM8 xenografts, median survivals were 46 d (PBS), 51 d with 1 mg/kg TMZ (+~11% vs PBS, p=0.004), 135 d with 5 mg/kg TMZ (+~193% vs PBS, p<0.001), and 167.5 d with 200 mg/kg EdU (+~264% vs PBS, p=0.001). Median survival was not reached for either TMZ+EdU regimen (1 mg/kg TMZ + 200 mg/kg EdU or 5 mg/kg TMZ + 200 mg/kg EdU); all animals were alive with no detectable tumor at Day 170, significantly outperforming each monotherapy. Short-course dosing followed by histology in U87-bearing mice showed marked tumor-cell selectivity of EdU (~70-83-fold in tumor cells vs adjacent non-tumor cells). In living, passage-zero GBM patient tumor tissues on OBSC, TMZ+EdU was synergistic in 1/4 tumors (ZIP 14) and additive in the remainder (ZIP 2-3).\nConclusions: TMZ and EdU act through distinct DNA repair pathways to deliver synergistic antitumor activity across GBM cell lines, mouse models of GBM, and living, passage-zero GBM patient tumor tissues. Given EdU’s brain penetration, the survival benefit observed preclinically, and the demonstration of synergy in a subset of GBM patient tumor tissues, TMZ+EdU represents a compelling strategy for translational development in GBM.", "source_company": "University of North Carolina at Chapel Hill", "source_org_type": "大学", "row_number": 322, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "X", "company": "University of Trento", "org_type": "大学", "target": "未披露", "modality": "vaccine", "importance_level": "中", "total_score": 52, "institution_score": 35, "track_score": 75, "milestone_score": 45, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "X为临床采用的疫苗平台，用于前列腺癌免疫冷肿瘤的改造，靶点未明确披露。大学机构得分较低但疫苗+新免疫原性表位赛道具有较高热度，前临床小鼠模型显示一定T细胞浸润和中性粒细胞募集，整体潜力中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5247", "id": "h1XM_5wBX1NQZOEH-LG5", "source_drug_name": "X", "title": "A clinical-adopted vaccine platform and new immunogenic epitopes combined against prostate cancer", "abstract_text": "Introduction: Prostate cancer (PCa) is the archetype of an immunological “cold” tumour, characterised by a very low mutational burden and neoantigen presentation, and minimal immune infiltration. In line with this, immune therapies turn out to be ineffective in PCa. The project aims at transforming PCa into an immunocompetent tumour through the development of ad hoc vaccinal strategies.\nMethods and Results: Recruiting adaptive immune cells into the prostate gland: The efficacy of a versatile clinical-adopted vaccine platform (X) to attract the immune system into the prostate tumour is under study in mouse model of advanced PCa. Immunohistochemistry on formalin-fixed paraffin-embedded (FFPE) slides of PCa allografts is defining the tumour microenvironment (TME) composition. Cd8+ T-cells infiltrate PCa tumours, while Cd4+ T-cells and FoxP3+ regulatory T-cells preferentially accumulate in the periphery. A dense network of Collagen VI fibrils might be responsible for the different distribution. Intratumoral injection of X adjuvants does not change T cells behaviour, but it stimulates the formation of tumour abscesses surrounded by tightly packed neutrophils. Identifying immunogenic antigens to instruct effector T cells against PCa: Non-canonical human leukocyte antigen (HLA)-restricted PCa antigens are caught among peptides coming from aberrant splicing events, expression of transposable elements and atypical expression of tissue/development-restricted genes thanks to the integration of in-depth RNA Seq transcriptome with mass spectrometry HLA-I epitome analyses.\nConclusions: We expect that the ability to attract the immune system into the prostate combined with the identification of immunogenic epitopes, will pave the way for the development of tailored and affordable vaccine therapies for the effective treatment of advanced PCa.", "source_company": "University of Trento", "source_org_type": "大学", "row_number": 400, "target_meta": "not available", "MOA_meta": "疫苗"}, {"drug_name": "CAR T cell therapy", "company": "St. Jude Children's Research Hospital", "org_type": "医院", "target": "未披露", "modality": "CAR", "importance_level": "中", "total_score": 52, "institution_score": 45, "track_score": 85, "milestone_score": 30, "field_heat_score": 80, "bonus_score": 0, "brief_reason": "CAR-T细胞疗法针对儿科血液肿瘤，靶点未在摘要中披露（无摘要），属于细胞治疗热门赛道。机构为知名儿科肿瘤专科医院但非商业药企导致机构分较低，开发阶段信息缺失致里程碑分低，总分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6039", "id": "4lXM_5wBX1NQZOEH-LK6", "source_drug_name": "CAR T cell therapy", "title": "Advancing CAR T cell therapy for pediatric blood cancers", "abstract_text": "There is no abstract associated with this presentation.", "source_company": "St. Jude Children's Research Hospital", "source_org_type": "医院", "row_number": 634, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "epigenetic reprogramming factors (ERFs)", "company": "Sanford Burnham Prebys Med. Discovery Inst.", "org_type": "研究机构", "target": "未披露", "modality": "other", "importance_level": "中", "total_score": 52, "institution_score": 35, "track_score": 75, "milestone_score": 55, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "通过异位表达表观遗传重编程因子（ERFs）逆转T细胞耗竭的表观遗传景观，改善T细胞功能并增强ACT疗效（如TIL和CAR-T）。研究机构背景得分较低，但T细胞耗竭重编程属于免疫治疗热门创新赛道，体内外数据展示一定概念验证价值。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5237", "id": "GlXM_5wBX1NQZOEH-LS6", "source_drug_name": "epigenetic reprogramming factors (ERFs)", "title": "Epigenetic reprogramming of T cell exhaustion", "abstract_text": "During tumor progression, T cells are recruited to the tumor microenvironment (TME), where T cells experience hypoxia, nutrient deprivation, immunosuppressive cytokines, and continuous stimulation by tumor antigens. These harsh conditions drive global epigenetic remodeling of T cells and promote their transition into a state of T cell exhaustion, characterized by impaired capacity in proliferation, reduced production of proinflammatory cytokines, and diminished self-renewal. Immune checkpoint blockade (ICB) treatment has revolutionized cancer therapy; however, it fails to reprogram the exhaustion-associated epigenetic landscape and therefore only partially restores T cell functions. Here, we aim to prevent T cell exhaustion by targeting this epigenetic landscape through ectopic expression of epigenetic reprogramming factors (ERFs). To this end, we first generated a mouse model with inducible ERF expression, isolated CD8+ T cells, and cultured them under hypoxic conditions with continuous stimulation, to mimic the TME. Under these conditions, ectopic expression of ERF factors significantly downregulates expression of exhaustion markers such as Tim3. We next assessed whether ERF-mediated reprogramming can restore the T cell function. In vitro, ERF-reprogrammed T cells exhibit increased durability compared to non-reprogrammed control T cells in response to exhaustion signals. In vivo, ERF-reprogrammed T cells, when transferred into tumor-bearing mice, significantly delays the tumor growth compared with transfer of non-ERF-expressing control T cells. Transcriptomics profiling further reveals that ERF reprogramming upregulates the genes involved in T cell activation, proliferation, and epigenetic remodeling. Collectively, these data support ERF-mediated reprogramming of T cells as a promising strategy to reshape the entrenched exhaustion-associated epigenetic landscape and restore T cell functions, with the potential to improve adoptive cell transfer (ACT)-based therapy such as Tumor-Infiltrating Lymphocytes (TIL) and Chimeric Antigen Receptor (CAR) T therapy.", "source_company": "Sanford Burnham Prebys Med. Discovery Inst.", "source_org_type": "研究机构", "row_number": 849, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "R7-CLIC1pep-linked E3 ligase peptide", "company": "Kyungpook National University", "org_type": "大学", "target": "CLIC1", "modality": "PROTAC", "importance_level": "中", "total_score": 52, "institution_score": 35, "track_score": 85, "milestone_score": 45, "field_heat_score": 60, "bonus_score": 4, "brief_reason": "该药物为针对CLIC1的PROTAC降解剂，CLIC1在多种癌症中上调并与血管生成、迁移和转移相关，属于新兴潜在靶点；采用ProTAC模态结合细胞穿透肽实现胞内降解，机制新颖但仅停留在体外细胞水平验证，机构为韩国大学非头部药企导致整体重要性中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4707", "id": "e1XM_5wBX1NQZOEH-LS6", "source_drug_name": "R7-CLIC1pep-linked E3 ligase peptide", "title": "Identification and functional analysis of chloride intracellular channel protein 1-binding peptide and its uses for ProTac-based cancer therapy", "abstract_text": "Targeted therapy using antibodies that treat only certain cancer cells is currently being studied because it causes less side effects on normal cells. Compared to antibodies, peptides are relatively smaller and have higher tissue penetration ability and lower immunogenicity. Chloride intracellular channel protein1 (CLIC1) is a metamorphic protein as it can exist in two forms: soluble globular protein in the cytoplasm or transmembrane protein. CLIC1 is related to cancer angiogenesis, cell migration and metastasis and is upregulated in various types of cancer, including hepatocellular carcinoma and lung cancer, presenting it as a promising therapeutic cancer target. In this study, we identified a peptide candidate (CLIC1pep) that binds to CLIC1 using phage display. The affinity and specific binding of CLIC1pep to CLIC1 was validated by SPR, ELISA, and pull-down assays. CLIC1pep linked to a cell-penetrating peptide (R7) (R7-CLIC1pep) showed an increased cell penetration and binding to CLIC1 in the cytoplasm, whereas it did not induce tumor cell death. However, R7-linked CLIC1pep inhibited the membrane insertion of CLIC1 and reduced the migration and invasion of cancer cells through reducing the p-ERK levels. Moreover, R7-CLIC1pep-linked E3 ligase peptide was synthesized for a ProTAC against CLIC1 and degraded CLIC1 in tumor cells. These results suggest that R7-CLIC1pep and R7-CLIC1pep-linked E3 ligase peptide hold a potential for a ProTac-based cancer therapy of CLIC1-high tumors.", "source_company": "Kyungpook National University", "source_org_type": "大学", "row_number": 918, "target_meta": "CLIC1,CLIC1", "MOA_meta": "PROTAC"}, {"drug_name": "PROGENTAC", "company": "Arizona State University", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "中", "total_score": 52, "institution_score": 35, "track_score": 85, "milestone_score": 40, "field_heat_score": 70, "bonus_score": 5, "brief_reason": "PROGENTAC为DNA框架双功能嵌合体，同时实现蛋白降解(DTAC靶向Cyclin D1-CDK4/6复合物)和基因沉默(ASO)，属于创新型小核酸+PROTAC-like融合技术。大学早期概念验证阶段，创新机制获bonus，但机构和开发阶段限制总体评分。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6446", "id": "KJ7M_5wBZznHJdnt_W3O", "source_drug_name": "PROGENTAC", "title": "Proteolysis and gene silencing targeting chimera (PROGENTAC)", "abstract_text": "Introduction: In biological systems, nucleic acids mirror computational networks, integrating digital genetic codes with analog molecular interactions to achieve precise, context-dependent control of life processes. Harnessing this property provides an opportunity to design programmable therapeutics with exceptional specificity and minimal toxicity. Building on this inspiration, we devised a method for the conditional activation of a dual-functional nucleic acid construct comprising gene-silencing antisense oligonucleotide (ASO) and protein degrader, a DNA-based proteolysis-targeting chimera. We have coined the term “Proteolysis Gene Silencing Targeting Chimera” (PROGENTAC) to describe this technology. This dual functionality of conditional PROGENTAC offers several advantages, such as enhanced specificity and combating multidrug-resistant in complex diseases1. The molecular design of PROGENTAC consists of three elements: 1) DNA-templated, spatially controlled protein-degrading chimera (DTAC) platform2; 2) ASO for targeted gene modulation; and 3) rationally proposed conditional nucleic acid-based molecular framework that regulate PROGENTAC activity3 in response to disease-specific intracellular cues or chemical trigger.\nExperimental Procedures: In house solid phase oligo synthesis was utilized to construct both DTAC and modified ASO constructs. In house organic synthesis was utilized to modify small molecule-based inhibitors. Electrophoretic mobility shift assay (EMSA) was utilized to visualize conditional activation of PROGENTAC in cell-free based media. Fluorescence resonance energy transfer (FRET) assay was utilized to evaluate kinetics of PROGENTAC activation. Additional experiments were conducted including, Cell treatments, Western blots, Confocal imaging, Flow Cytometry, Proteomics, and Cytotoxicity assays.\nResults and Summary: Three cancer cell lines U251, A549 and AU565 showed excellent activity of DTAC that targets Cyclin D1-CDK4/6 complex protein with efficacy of DC50 of 20-100 nM range. For a proof of concept, we successfully constructed GFP protein silencing ASO construct with various nucleic acid modifications such as 2’-OMe, locked nucleic acid (LNA), and phosphorothioate (PS backbone). The optimal chemically modified potent ASO construct was successfully integrated with DTAC in PROGENTAC molecular framework. PROGENTAC construct was evaluated for structural stability and conditional activation to release both protein degrading DTAC and gene silencing ASO modalities. In the conference we will further talk about extended cellular results and therapeutic properties of PROGENTAC.\nCitation: 1) Dagogo-Jack, I. & Shaw, A. T. Nat Rev Clin Oncol 15, 81-94 (2018); 2) Zheng, L. et al. J. Am. Chem. Soc. 2025, 147, 33, 29742-29755; 3) Yan, H., Zhang, X., Shen, Z. et al. Nature 415, 62-65 (2002).", "source_company": "Arizona State University", "source_org_type": "大学", "row_number": 978, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "Multi-Antigen T Cell Hybridizers (MATCH)", "company": "University of Utah", "org_type": "大学", "target": "未披露", "modality": "TCE", "importance_level": "中", "total_score": 52, "institution_score": 35, "track_score": 85, "milestone_score": 40, "field_heat_score": 75, "bonus_score": 3, "brief_reason": "MATCH为新型模块化T细胞衔接器（TCE），通过自组装桥接T细胞与多抗原肿瘤细胞，实现可调谐免疫治疗，但靶点未在AACR摘要中披露。大学机构非商业化主体得分为35，TCE多抗原策略在热门免疫治疗赛道具较高热度和潜力，但仅preclinical阶段且摘要禁运导致里程碑信息有限，总分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11424", "id": "ap7M_5wBZznHJdnt_W3O", "source_drug_name": "Multi-Antigen T Cell Hybridizers (MATCH)", "title": "A modular Multi-Antigen T Cell Hybridizers (MATCH) platform enables tunable and potent immunotherapy across hematologic and solid tumors", "abstract_text": "Abstract is embargoed at this time.", "source_company": "University of Utah", "source_org_type": "大学", "row_number": 1020, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "CAR T cells", "company": "Peter MacCallum Cancer Centre", "org_type": "医院", "target": "未披露", "modality": "CAR", "importance_level": "中", "total_score": 52, "institution_score": 45, "track_score": 85, "milestone_score": 30, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "药品为CAR-T细胞，属于细胞治疗热门赛道，但靶点和具体工程细节未在摘要中披露，仅标题提示精准靶向工程。机构为知名癌症医院而非头部药企，开发阶段信息缺失导致里程碑分较低，总分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/772", "id": "qJ3ECZ0B4z9FlvORyiZD", "source_drug_name": "CAR T cells", "title": "Precision targeted engineering of CAR T cells", "abstract_text": "There is no abstract associated with this presentation.", "source_company": "Peter MacCallum Cancer Centre", "source_org_type": "医院", "row_number": 1073, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "immune checkpoint blockade", "company": "The Jackson Laboratory", "org_type": "研究机构", "target": "未披露", "modality": "immune checkpoint blockade", "importance_level": "中", "total_score": 52, "institution_score": 35, "track_score": 85, "milestone_score": 40, "field_heat_score": 80, "bonus_score": 0, "brief_reason": "摘要聚焦neoadjuvant免疫检查点阻断在转移性黑色素瘤中的响应机制与空间免疫特征研究，而非具体药物靶点披露。研究机构非药企导致机构分较低，但免疫检查点领域整体热度高、临床意义重大，故综合为中等重要性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9473", "id": "rZ3ECZ0B4z9FlvORyiZD", "source_drug_name": "immune checkpoint blockade", "title": "Spatially resolved immunologic hallmarks of response to neoadjuvant immune checkpoint blockade in metastatic melanoma", "abstract_text": "Background: The recent groundbreaking neoadjuvant immune checkpoint blockade (NICB) clinical trials in melanoma have demonstrated decisively that the administration of ICB prior to intent-to-cure surgeries will become the new standard-of-care for metastatic melanoma and beyond. The paradigm shifts from radiographic to pathologic response assessment also presents an unparalleled “window of opportunity” for the acquisition of abundant “on-treatment” tissues to elucidate the mechanisms and biomarkers of response and for guiding post-surgery personalized therapy decisions. To date, single-cell/bulk RNA studies have demonstrated that TCF7+ stem-like CD8+ T cells and tertiary lymphoid structures (TLS) are positive predictors of ICB response. However, how these immune cells organize and communicate within the spatial context of the neoadjuvant tumor microenvironment remains poorly understood.\nMethods: We investigated a unique cohort of 91 FFPE biospecimens from 87 patients with stage III metastatic melanoma, including 60 treated with NICB (31 complete response, 7 partial response, 22 non-response) and 27 treatment-naïve. We deployed state-of-the-art technologies, including multiplexed error-robust fluorescent in situ hybridization (MERFISH), single cell sequencing of FFPE blocks, and multiplexed IF for this rich digital resource. Importantly, to analyze these challenging high dimensional spatial datasets, we developed 3 novel computational algorithms, including SCIRA, a scalable quantification method for spatial receptor-ligand (R-L) interactions; GC-SCAN, a graph-based clustering method to detect Germinal Center (GC)/TLS structures in single cell spatial data; and PathNet, an end-to-end AI algorithm for automated GC/TLS detection on H&E slides.\nResults: Here, we interrogated ~5.6 million cells and showed that increased GC/mature TLSs, TCF7+ stem-like CD8 and CD4 T-cells, exhausted CD8 T-cells, plasma cells and myeloids in spatially distinct cellular neighborhoods are significantly associated with positive response. Our spatial (R-L) analyses further identified preferential chemokine R-L interactions between GC-B cells and follicular helper T-cell, and TCF7+ stem-like T-cells with CCL19+/CCL21+ fibroblasts in organizing these immune hubs. Lastly, Our PathNet GC/TLS detection algorithm outperforms recent state-of-the-art methods in both specificity and sensitivity, proven potential utility in facilitating clinical response assessment.\nConclusions: We leveraged cutting-edge spatial-omics technologies and novel computational methods to resolve the immunologic hallmarks of NICB response in metastatic melanoma. We believe our approach provides a model for how to precisely identify spatially intricate immune interactions that underline treatment response in the rapidly advancing era of standard of care neoadjuvant immunotherapy.", "source_company": "The Jackson Laboratory", "source_org_type": "研究机构", "row_number": 1093, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "anti-PD-L1 antibody", "company": "Mayo Clinic Hospital-Rochester", "org_type": "医院", "target": "PD-L1", "modality": "inhibitor", "importance_level": "中", "total_score": 51.8, "institution_score": 35, "track_score": 75, "milestone_score": 45, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "研究揭示PD-L1乙酰化开关调控cohesin结合与染色体稳定性，deacetylation突变体激活cGAS-STING通路并增强对anti-PD-L1抗体的免疫敏感性。机构为医院学术型得分较低，但新机制发现与PD-L1免疫治疗增敏潜力带来一定track与field热度。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/7316", "id": "ElXM_5wBX1NQZOEH-LS6", "source_drug_name": "anti-PD-L1 antibody", "title": "A pd-l1 acetylation switch coordinates chromosome cohesion and antitumor immunity", "abstract_text": "Background: PD-L1 is best known for suppressing antitumor immunity at the cell surface, yet emerging evidence suggests additional nuclear functions. Previous studies from our laboratory demonstrated that nuclear PD-L1 interacts with the cohesin complex to maintain chromosomal stability. However, the upstream regulatory mechanism governing this interaction and its immunological consequences remain unknown.\nMethods and Results: Using acetylation-site prediction, mutagenesis, and structural modeling, we identified lysine 178 (human) / 177 (mouse) as a conserved acetylation switch regulating PD-L1 function. Deacetylation of PD-L1 (K178R/K177R) disrupted PD-L1-PDS5B/cohesin binding without affecting subcellular localization. This led to defective sister chromatid cohesion, micronuclei formation, and cytosolic DNA accumulation. RNA-seq, qPCR, and immunoblotting demonstrated robust activation of the cGAS-STING-IFN-γ signaling axis and enhanced MHC-I antigen-presentation machinery in PD-L1 K178R cells. Functionally, K178R cells proliferated more slowly and were highly susceptible to PBMC-mediated killing in co-culture assays, with further enhancement upon anti-PD-L1 antibody treatment. In xenograft models (NSG mice), tumors expressing PD-L1 K178R grew significantly slower than WT. In immunocompetent C57BL/6 syngeneic models, PD-L1 K177R tumors showed reduced growth and heightened responsiveness to PD-L1 blockade. Structural and biochemical analyses confirmed that PD-L1 acetylation at K178/K177 stabilizes its interaction with the cohesin complex, thereby preventing chromosomal instability-induced immune activation.\nConclusions: We identify a conserved PD-L1 acetylation switch that couples cohesin stability to innate immune activation. PD-L1 deacetylation promotes chromosomal instability, activates cGAS-STING-IFN-γ signaling, enhances antigen presentation, and sensitizes tumors to PD-L1 immunotherapy. These findings uncover a previously unrecognized regulatory axis linking tumor genomic integrity to immune recognition, providing a mechanistic foundation for targeting PD-L1 acetylation in cancer treatment.", "source_company": "Mayo Clinic Hospital-Rochester\nMayo Clinic", "source_org_type": "医院", "row_number": 70, "target_meta": "PDL1", "MOA_meta": "抑制剂"}, {"drug_name": "anti-PD-1 antibodies", "company": "Case Western Reserve University", "org_type": "大学", "target": "PD-1", "modality": "inhibitor", "importance_level": "中", "total_score": 51.8, "institution_score": 25, "track_score": 75, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "anti-PD-1抗体为经典免疫检查点抑制剂，联合HER3抑制在mCRC/mPC肝转移模型中显著提高疗效并实现约40%完全缓解。大学机构分数较低，但赛道和联合策略的潜在临床转化价值使其整体处于中等重要性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9428", "id": "qp3ECZ0B4z9FlvORyiZD", "source_drug_name": "anti-PD-1 antibodies", "title": "HER3 inhibition sensitizes metastatic colorectal and pancreatic cancer to immunotherapy", "abstract_text": "INTRODUCTION: Metastatic colorectal cancer (mCRC) and pancreatic cancer (mPC) demonstrate 5-year survival rates of 14% and 3%, respectively, with over 70% patients developing distant metastases in the liver. Immune checkpoint inhibitors (ICIs) exhibit significant efficacy in some solid tumors and MSI CRC but have limited therapeutic benefit in MSS mCRC/mPC. This project aims to identify potential novel combination strategies to overcome ICIs resistance in mCRC/mPC. We previously discovered that liver endothelial cells activate HER3 signaling in cancer cells through NRG1 and LRG1 ligands, promoting metastatic growth via distinct AKT/RSK pathways. This study investigates whether inhibiting HER3 pathway can enhance immunotherapy efficacy in mCRC/mPC, especially MSS tumors.\nMETHODS: Metabolic changes in CRC/PC cells and tumors were first determined by LC-MS and ELISA for key metabolites, and then further assessed by in vitro assays, including Seahorse FX and TMRE, in the context of HER3 activation and/or inhibition. Phosphorylation activation of HER3 and downstream metabolic enzymes were evaluated by Western blotting and IHC staining using murine/patient tumor tissues. We developed syngeneic, orthotopic CRC/PC liver metastases by hepatic injection of murine CRC and PC cells (MSI or MSS), and assessed T cell infiltration and activation by IHC staining and flow cytometry. More importantly, therapeutic efficacy was assessed by treating these models with HER3 inhibitor sapitinib and/or anti-PD-1 antibodies.\nRESULTS: LC-MS analysis revealed that mCRC/mPC exhibited significantly elevated glycolytic metabolites compared to primary tumors, with HER3 inhibition reversing this metabolic reprogramming. HER3 activation enhanced phosphofructokinase 2 (PFK2)-S483 phosphorylation and increased lactate secretion in CRC/PC cells. In murine CRC/PC liver metastases, HER3 KO tumors showed decreased lactate, which reduced exhaustion of CD8+ T cells, determined by decreased expression of TOX, and increased cytotoxic CD8+ T cells, determined by increased Granzyme B levels. Most importantly, the combination of HER3 inhibition with anti-PD-1 significantly extended survival in CRC/PC liver metastases (both MSI and MSS), and achieved ~40% complete response rate, which is markedly superior to monotherapies.\nCONCLUSIONS: We identify a novel HER3-PFK2-lactate metabolic axis that promotes immunosuppression in CRC/PC liver metastases. Targeting this pathway sensitizes CRC/PC liver metastases to checkpoint blockade, offering a promising strategy to extend immunotherapy benefits beyond the limited patient population currently responsive to ICIs.", "source_company": "Case Western Reserve University", "source_org_type": "大学", "row_number": 1082, "target_meta": "PD1", "MOA_meta": "抑制剂"}, {"drug_name": "RMP1-14", "company": "Mayo Clinic Hospital-Rochester", "org_type": "医院", "target": "PD-1", "modality": "inhibitor", "importance_level": "中", "total_score": 51.5, "institution_score": 35, "track_score": 75, "milestone_score": 50, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "RMP1-14为鼠源anti-PD-1单抗（inhibitor），用于pMMR直肠癌模型中联合高LET辐射和ATM抑制剂显著提升PD1i疗效并实现原发/远隔肿瘤完全缓解。机构为医院/学术型得分较低，但PD-1赛道经典且与创新辐射组合显示预临床协同潜力，故综合为中等重要性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9487", "id": "AlXM_5wBX1NQZOEH-LG5", "source_drug_name": "RMP1-14", "title": "Particle therapy, ATM and PD-1 inhibition for pMMR rectal cancer", "abstract_text": "Background and Aims: Colorectal cancer is a leading cause of cancer mortality and most rectal cancers are mismatch repair proficient (pMMR), making them largely resistant to PD-1 inhibitors (PD1i). While PD1i achieves excellent complete response rates in MMR-deficient tumors, these represent <5% of rectal cancers. For the remaining 95% of patients, effective immunotherapy strategies are urgently needed. We evaluated two high-LET radiation approaches to prime pMMR rectal cancers to PD1i and enhance local control: 1) Diffusing alpha emitter Radiation Therapy (DaRT) implants, and 2) LET-optimized (Bragg Peak) protons + ATM inhibitor. An ATM inhibitor was evaluated with protons to evaluate whether it could produce a more alpha/carbon-like effect given the lower comparative LETd achievable in clinical treatment plans.\nMethods: In vitro proton irradiation of HCT116, HT29, SW480, and CT26 was performed as previously with dose averaged LET (LETd) values of 2.2 keV/um for ENT and 7.0 keV/um for BP protons. Female Balb/C mice were subcutaneously inoculated with 1×10^6 CT26 cells on one flank and 1×10^5 cells on the contralateral flank to establish primary and secondary (abscopal) tumors, respectively. PD1i monoclonal antibody (RMP1-14 Bio X Cell) was administered i.p. 100ug every 72 hours for 4 total doses. The ATM inhibitor AZD1390 was delivered via oral gavage at 20 mg/kg, PO 1 hour prior to radiation. For in vivo studies, radiation was delivered using a PXI SmART small animal irradiator with opposing lateral beams (225 kVp, 20 mA, 0.3mm Cu filter). Proton irradiation plans were produced as previously described. We used mass cytometry by time of flight (CyTOF) using the TME CD45 lymphocyte subpopulations based on multiple cell markers.\nResult: In our preliminary data we demonstrate that both DaRT and BP protons+ATMi synergize with PD1i to dramatically increase complete response rates at both primary and abscopal tumors by increasing DNA damage, activating innate immune pathways, and reducing immunosuppression within the tumor microenvironment. Critically, this effect was observed in a pMMR model which did not respond to PD1i or conventional X-rays+PD1i, highlighting the innovation and potential impact of this work.\nConclusion: DaRT and BP protons ATMi prime pMMR colorectal cancer to PD1i, and all elements are clinically translatable.", "source_company": "Mayo Clinic Hospital-Rochester", "source_org_type": "医院", "row_number": 312, "target_meta": "PD1", "MOA_meta": "抑制剂"}, {"drug_name": "lipopolymer/siRNA nanoparticles (LPNPs)", "company": "University of Alberta", "org_type": "大学", "target": "KMT2A::AFF1, KMT2A::MLLT3, BCR::ABL1", "modality": "other", "importance_level": "中", "total_score": 51.5, "institution_score": 25, "track_score": 75, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 2, "brief_reason": "采用脂聚物递送siRNA平台靶向多种融合癌基因（KMT2A::AFF1等），在白血病异种移植模型中显著降低肿瘤负荷并延长生存；大学机构得分较低，但siRNA递送+融合基因靶向在血液瘤领域有较好preclinical强度和潜在转化价值。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5559", "id": "CVXM_5wBX1NQZOEH-LG5", "source_drug_name": "lipopolymer/siRNA nanoparticles (LPNPs)", "title": "Lipopolymer-mediated delivery of fusion oncogene-targeting siRNAs attenuates leukemia burden and improves survival in preclinical models of hematologic malignancies", "abstract_text": "Hematologic malignancies are genetically heterogeneous cancers marked by a range of chromosomal translocations, among which fusion oncogenes, e.g., KMT2A::AFF1 in acute lymphoblastic leukemia (ALL), KMT2A::MLLT3 in acute myeloid leukemia (AML), and BCR::ABL1 in chronic myeloid leukemia (CML), are particularly aggressive and clinically intractable. These fusion-driven hematologic malignancies are associated with poor prognosis and resistance to conventional therapies, emphasizing the need for fusion targeted, personalized treatment strategies. Small interfering RNAs (siRNAs) offer a promising approach due to their capacity for precise gene silencing. However, clinical translation is hindered by delivery challenges, including rapid degradation, off-target effects, hepatic accumulation, and inefficient uptake by hematopoietic cells, largely due to their negative charge, size, and the limited cytoplasmic volume of blood cells.\nTo address these limitations, we developed a novel lipopolymer-based siRNA delivery platform by conjugating aliphatic lipids onto low-molecular-weight polyethyleneimine (PEI, 1.2 kDa). This modification yielded a series of lipopolymers capable of forming stable nanocomplexes with siRNAs, colloquially known as lipopolymer/siRNA nanoparticles (LPNPs). These LPNPs leverage the cationic nature of PEI for siRNA binding and lipid-mediated mechanisms to enhance cellular uptake. We evaluated the efficacy of LPNPs in delivering siRNAs targeting KMT2A::AFF1, KMT2A::MLLT3, and BCR::ABL1 in preclinical models of ALL, AML, and CML, respectively.\nLPNP-mediated delivery attained efficient intracellular siRNA uptake and robust gene silencing in all three forms of leukemia cell lines, which resulted significant downregulation of fusion oncogene expression. This silencing induced apoptosis and markedly reduced colony-forming potential in vitro. In vivo biodistribution studies demonstrated enhanced biodistribution of LPNPs in leukemia-accompanying tissues, including bone marrow and spleen, with reduced hepatic sequestration. Particularly, systemic administration of LPNPs led to a substantial reduction in leukemia burden and significantly improved survival in xenograft models of ALL, AML, and CML.\nOur findings highlight the therapeutic potential of lipopolymer-mediated siRNA delivery for targeting fusion oncogenes in hematologic malignancies. This platform offers a promising strategy for overcoming current delivery barriers and advancing RNA interference-based therapies toward clinical application.", "source_company": "University of Alberta", "source_org_type": "大学", "row_number": 319, "target_meta": "Bcr-Abl", "MOA_meta": "其他"}, {"drug_name": "mutant IDH2 hyperactivator", "company": "Memorial Sloan Kettering Cancer Center", "org_type": "医院", "target": "mutant IDH2", "modality": "inhibitor", "importance_level": "中", "total_score": 51.5, "institution_score": 35, "track_score": 75, "milestone_score": 45, "field_heat_score": 70, "bonus_score": 5, "brief_reason": "药物通过hyperactivation mutant IDH2将代谢转为致死弱点，实现选择性杀伤IDH2突变癌细胞，提出全新治疗策略而非传统抑制。机构为顶尖癌症医院但非药企、仍处机制发现及化学筛选早期阶段、赛道涉及代谢靶点新机制故打分中等偏上。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8845", "id": "ElXM_5wBX1NQZOEH-LG5", "source_drug_name": "mutant IDH2 hyperactivator", "title": "Enzyme hyperactivation to target isocitrate dehydrogenase mutations", "abstract_text": "Somatic mutations in isocitrate dehydrogenase (IDH) enzymes are hallmarks of acute myeloid leukemia (AML), glioma, and several other cancers. Mutations in IDH result in the neomorphic ability to convert alpha-ketoglutarate (α-KG) into the oncometabolite 2-hydroxyglutarate (2HG), which competitively inhibits α-KG-dependent enzymes and locks malignant cells in a stem cell-like state. Targeted inhibition of mutant IDH enzymes effectively shuts off production of the oncometabolite 2HG and benefits some patients with IDH-mutant cancers. However, the majority of IDH-mutant tumors are impervious to 2HG inhibition. Even for those cases that respond to mutant IDH inhibition, drug resistance invariably develops. Thus, there is an unmet need for novel therapeutic approaches beyond simple inhibition of mutant IDH. Based on mechanistic studies of an unusual drug resistance mutation identified in patients with acquired resistance to IDH inhibitors, we discovered that genetic hyperactivation of mutant IDH2 converts the activity of mutant IDH2 into a lethal metabolic liability. Using chemical screens, we identified small molecules that hyperactivate mutant IDH2, unleash metabolic toxicity, and selectively eliminate IDH2-mutant cancer cells. Thus, we propose that hyperactivation (rather than inhibition) of mutant IDH offers an unexpected and effective new therapeutic approach for targeting IDH-mutant cancers.", "source_company": "Memorial Sloan Kettering Cancer Center", "source_org_type": "医院", "row_number": 323, "target_meta": "IDH2", "MOA_meta": "抑制剂"}, {"drug_name": "antibody-drug conjugate", "company": "Eurofins DiscoverX", "org_type": "公司", "target": "未披露", "modality": "ADC", "importance_level": "中", "total_score": 51.5, "institution_score": 45, "track_score": 85, "milestone_score": 30, "field_heat_score": 80, "bonus_score": 0, "brief_reason": "该摘要为Eurofins DiscoverX公司展示的ADC综合表征平台和技术方法，靶点和具体药物未披露，仅涉及通用ADC机制研究（BCMA、CD33示例）。机构为CRO服务型公司而非药物研发主体得较低分，ADC赛道热度高但无具体里程碑进展得中分，总分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4472", "id": "mlXM_5wBX1NQZOEH-LG6", "source_drug_name": "antibody-drug conjugate", "title": "Integrated evaluation of payload-, Fc-, and target-mediated mechanisms of ADCs using streamlined complementary platforms", "abstract_text": "This study demonstrates an integrated approach for comprehensive characterization of antibody-drug conjugates (ADCs) using complementary bioanalytical platforms. The objective was to evaluate target binding, internalization, and both payload- and Fc-mediated cytotoxic mechanisms to generate a holistic understanding of ADC mode of action.ADC binding affinity and kinetic parameters were characterized by surface plasmon resonance microscopy (SPRm) to assess cell-surface receptor engagement. Internalization was measured in engineered tumor cell lines expressing relevant antigens (e.g., BCMA, CD33) using enzyme-fragment complementation (EFC)-based PathHunter® internalization assays. Functional cytotoxicity was quantified using the KILR® Cytotoxicity platform, providing direct readouts of target-cell death. Fc-effector functions, including antibody-dependent cellular cytotoxicity (ADCC) and phagocytosis (ADCP), were evaluated using effector cell models to distinguish immune-mediated from payload-driven mechanisms.Here we show characterization data for 2 different ADCs which demonstrated high-affinity binding by SPRm and efficient internalization by PathHunter assays. In KILR assays, the ADC produced a concentration-dependent cytotoxic response distinct from its unconjugated parental antibody. Comparative analysis revealed that payload-mediated killing dominated overall cytotoxicity, while measurable ADCC and ADCP activities reflected retained Fc function. Integration of biophysical and cell-based results provided mechanistic resolution of ADC function at multiple levels. Combining SPRm, PathHunter internalization assays, and KILR cytotoxicity enables comprehensive ADC characterization encompassing binding, uptake, and multi-mechanistic cytotoxicity. This integrated workflow supports discovery, optimization, and lot-release testing by linking molecular properties to functional outcomes, enhancing mechanistic understanding critical for ADC development.", "source_company": "Eurofins DiscoverX", "source_org_type": "公司", "row_number": 416, "target_meta": "not available", "MOA_meta": "抗体偶联药物"}, {"drug_name": "WEE1 inhibitor", "company": "H. Lee Moffitt Cancer Center & Research Institute", "org_type": "研究机构", "target": "WEE1", "modality": "inhibitor", "importance_level": "中", "total_score": 51.5, "institution_score": 35, "track_score": 75, "milestone_score": 45, "field_heat_score": 60, "bonus_score": 2, "brief_reason": "WEE1抑制剂针对POU2F3+ SCLC显示协同抗肿瘤活性，通过联合ALK/IGF1R抑制剂诱导POU2F3磷酸化失活这一新机制。机构为研究型癌症中心而非产业化药企、仍处机制探索与动物模型阶段导致总体评分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6576", "id": "QZ7ECZ0BZznHJdntvNYd", "source_drug_name": "WEE1 inhibitor", "title": "Novel therapeutic opportunities in POU2F3 transcription factor-driven small cell lung cancer", "abstract_text": "Small cell lung cancer (SCLC) is a recalcitrant cancer characterized by loss of TP53 and RB1. POU2F3+ SCLC cells are uniquely dependent on IGF1R signaling although this has not yet led to clinical translation. We therefore aimed to identify efficacious pharmacological targeting approaches for POU2F3+ SCLC and elucidate the underlying mechanisms.Cell viability was measured by CellTiter-Glo and soft agar assays. Drug targets and signaling pathways were identified by quantitative mass spectrometry-based proteomics and validated by Western blot. POU2F3 mutants were cloned to determine the kinase responsible for phosphorylation of POU2F3 the cellular effects of POU2F3 phosphorylation. Loss- and gain-of-function experiments were done using CRISPR, RNAi, chemical probes, or protein expression. Xenograft tumors were obtained by subcutaneous injection of POU2F3+ H526 cells into athymic nude mice. POU2F3 overexpressing, transgenic Rb1fl/flTrp53fl/fl(MycLSL/LSL) (RP/RPM) mice are being generated by genetic engineering and transfer of embryonic stem cells.Combination drug screening identified synergistic combinations between ALK-inhibitors with cross-reactivity for IGF1R and WEE1 inhibitors abrogating cell growth in vitro and in in vivo. Efficacy differences between the IGF1R inhibitors suggested the presence of additional druggable targets. Merging proteome-wide drug targets with changes in protein signaling and expression highlighted mTOR and cell cycle pathways and RSK1/2 as a relevant off-target. Interestingly, changes in both POU2F3 phosphorylation itself and expression of downstream POU2F3 transcriptional targets were identified upon individual or combination drug treatment and confirmed by immunoblotting. Rescue by overexpression of POU2F3 phospho-mutants upon CRISPR knockout of endogenous POU2F3 suggest an inhibitory function for pPOU2F3. Brigatinib and ceritinib, two potent FDA approved ALK/IGF1R inhibitors, were found to synergize with WEE1 inhibitors, in POU2F3+ SCLC. Quantitative, global chemical proteomics analysis found overlapping target profiles indicating favorable polypharmacology beyond IGF1R inhibition. Furthermore, quantitative phospho- and expression proteomics and subsequent genetic validation identified a novel regulatory mechanism of the oncogenic transcription factor POU2F3 by loss-of-function phosphorylation, which is strongly induced by drug combination treatment. This modification may indicate a new actionable vulnerability, which could be targeted to benefit the greatly underserved SCLC patient population.", "source_company": "H. Lee Moffitt Cancer Center & Research Institute", "source_org_type": "研究机构", "row_number": 484, "target_meta": "WEE1", "MOA_meta": "抑制剂"}, {"drug_name": "rMeV-MG53", "company": "Ohio State University", "org_type": "大学", "target": "未披露", "modality": "oncolytic virus", "importance_level": "中", "total_score": 51.5, "institution_score": 35, "track_score": 75, "milestone_score": 45, "field_heat_score": 65, "bonus_score": 3, "brief_reason": "rMeV-MG53为表达MG53的重组溶瘤麻疹病毒，通过直接溶瘤+焦亡诱导及免疫激活发挥抗肺癌作用，但靶点未明确为肿瘤特异性靶向。机构为大学得分较低，溶瘤病毒赛道热度较高但仍处于preclinical阶段，整体重要性中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9696", "id": "AVXM_5wBX1NQZOEH-LK6", "source_drug_name": "rMeV-MG53", "title": "Developing oncolytic measles virus expressing MG53 for the treatment of lung cancer", "abstract_text": "Background: Despite advances in lung cancer therapy, effective strategies that simultaneously eradicate tumors and stimulate antitumor immunity remain limited. Oncolytic virotherapy (OV) has emerged as a viable clinical approach for cancer immunotherapy option. Engineered attenuated measles virus strains offer several advantages: excellent safety profiles, tumor selectivity, lack of genotoxicity, and ease of genetic manipulation. MeV replicates preferentially in malignant cells and mediates anti-tumor effects not only on the cellular level by lytic infection of tumor cells, but also on the systemic level by priming anti-tumor immune responses. TRIM72, also known as Mitsugumin 53 (MG53), is a TRIM family protein secreted by muscle tissue and plays an anti-tumor role. In this study, we developed a recombinant measles virus expressing MG53 (rMeV-MG53) and investigated its dual ability to induce tumor cell death and activate antitumor immunity, as well as its potential synergy with immune checkpoint blockade in lung cancer models.\nMethods: An attenuated measles virus (MeV) Edmonston vaccine strain was engineered to express MG53, generating rMeV-MG53. A measles virus encoding the mCherry reporter gene served as control. Human lung cancer cell lines were used for in vitro studies to evaluate viral infectivity, oncolytic activity, pyroptosis induction, and inflammatory signaling, with Western blotting performed to assess caspase-3/GSDME activation. For in vivo studies, mouse lung cancer cells were engineered to express human CD46, rendering them susceptible to rMeV-MG53. hCD46-overexpressing cells were implanted into immunocompetent mice, followed by intratumoral administration of rMeV-MG53 alone or combined with anti-PD-L1 antibody.\nResults: In vitro, rMeV-MG53 efficiently infected human lung cancer cells and exhibited potent oncolytic activity. Western blot analysis demonstrated enhanced caspase-3/GSDME-mediated pyroptosis compared with rMeV alone. rMeV-MG53 also activated inflammatory signaling pathways, suggesting a role in promoting antitumor immunity. In vivo, CD46-overexpressing mouse lung cancer cells were highly sensitive to rMeV-MG53-mediated oncolysis. Intratumoral administration of rMeV-MG53 significantly suppressed tumor growth, with a more pronounced effect than rMeV alone. Combination therapy with rMeV-MG53 and anti-PD-L1 antibody further augmented antitumor efficacy.\nConclusion: These findings demonstrate that rMeV-MG53 exerts robust antitumor effects through direct induction of pyroptosis and activation of inflammatory signaling while synergizing with immune checkpoint blockade. rMeV-MG53 represents a promising oncolytic platform that integrates tumor cell killing with immune activation, offering translational potential as a novel therapeutic strategy for lung cancer.", "source_company": "Ohio State University\nThe Ohio State University", "source_org_type": "大学", "row_number": 490, "target_meta": "not available", "MOA_meta": "溶瘤病毒"}, {"drug_name": "chalcone derivatives", "company": "University of California, Irvine", "org_type": "大学", "target": "SKP2", "modality": "other", "importance_level": "中", "total_score": 51.5, "institution_score": 35, "track_score": 75, "milestone_score": 45, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "靶向SKP2的chalcone类小分子降解剂，在前列腺癌模型中显示特异性降解活性及选择性生长抑制。大学机构基础研究+早期筛选平台建立，得分主要来自SKP2在前列腺癌中的潜在价值及degrader赛道一定热度。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6768", "id": "B1XM_5wBX1NQZOEH-LK6", "source_drug_name": "chalcone derivatives", "title": "Development of HiBiT tagged high-throughput screening assay for the discovery of SKP2 targeting degraders in prostate cancer", "abstract_text": "S-phase kinase associated protein 2 (SKP2), an E3 ubiquitin ligase for protein degradation and regulating the cell cycle, is overexpressed in high-grade prostatic intraepithelial neoplasia and prostate adenocarcinoma compared to normal prostate tissues, and its higher mRNA levels in prostate tumor tissues are significantly associated with poorer survival of prostate cancer patients. Therefore, identifying novel molecules that promote SKP2 degradation represents a promising strategy for intercepting prostate cancer. We have generated the CRISPR/Cas9 knock-in (KI) of the HiBiT tag at the endogenous SKP2 locus in the 22Rv1 prostate cancer cell line with SKP2 gene amplification to enable high-throughput screening of SKP2 protein degraders. Sanger sequencing, western blot and luminescence imaging were performed to confirm the successful expression of the endogenous SKP2-HiBiT in 22Rv1 cells. Screening conditions adapted with nano-Glo® HiBiT lytic detection assay were well established in a 384 well plate format, yielding a high signal-to-background ratio of 69. We have further validated the screening assay with SKP2 C1 inhibitor and Flavokawain A, a naturally occurring chalcone from the Kava plants. Flavokawain A (degrading SKP2 protein) but not C1 (a SKP2 enzyme inhibitor) inhibited the HiBiT luminescence signal, confirming the specificity of the assay. In addition, we have synthesized a small library of chalcone derivatives and by screening them in SKP2-HiBiT-KI 22Rv1 cells, three new SKP2 degraders with improved efficacy have been identified. To avoid false positives due to assay artifacts, compounds that significantly inhibit luminescence within 5 minutes of treatment are excluded from the hits list. The screening assay exhibited robust performance with Z′ factors exceeding 0.6. These three SKP2 degraders significantly reduced the HiBiT luminescent signal at low micromolar concentrations after 8 hours of treatment compared to vehicle control treatment, with minimal effects on cell viability. Western blot analyses further confirmed that these three hits downregulated the protein levels of SKP2 in a dose and time dependent manner. In addition, PC3 cells overexpressing SKP2 are more sensitive to the growth inhibitory effects of these three degraders than SKP2 non-overexpressing PC3 control cells, suggesting the specificity of these degraders for targeting SKP2 overexpressing prostate cancer cells. In conclusion, we successfully established and validated the SKP2-HiBiT-KI 22Rv1screening platform that enables the identification of highly potent, low-toxicity SKP2 degraders for prostate cancer interception.", "source_company": "University of California, Irvine", "source_org_type": "大学", "row_number": 495, "target_meta": "SKP2", "MOA_meta": "其他"}, {"drug_name": "nanobody clone 9-1-12", "company": "UTSW", "org_type": "大学研究机构", "target": "未披露", "modality": "nanobody", "importance_level": "中", "total_score": 51.5, "institution_score": 35, "track_score": 75, "milestone_score": 45, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "nanobody clone 9-1-12为靶点未知的单域抗体，通过功能性表型筛选获得，能显著增强CD8 T细胞激活并对抗PD-L1抑制，体现target-agnostic免疫调控潜力。机构为知名学术中心但非头部药企得较低分，热门nanobody+免疫治疗赛道及功能验证里程碑贡献中高分，总分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5651", "id": "YFXM_5wBX1NQZOEH-LK6", "source_drug_name": "nanobody clone 9-1-12", "title": "Target agnostic phage display for nanobodies that alter immune cell function", "abstract_text": "Introduction: The discovery of novel cancer immunotherapies is currently limited by a reliance on known antigens and screens that prioritize binding affinity over function. To overcome this, we developed INSPIRE-seq, a platform integrating NGS and phage display to unbiasedly select for nanobodies against cell subtypes within the tumor microenvironment (TME). Here, we advance this technology to address a critical unmet need: the direct isolation of nanobodies that functionally modulate immune cell behavior. Our objective is to move beyond simple binding and deploy a strictly target-agnostic strategy to identify therapeutic candidates based solely on their ability to enhance T cell efficacy, without prior knowledge of their molecular targets.\nExperimental Procedures: To validate this functional selection strategy, we established an ex vivo model using bead-purified naïve CD8 T cells. Cells were activated with αCD3 and αCD28 antibodies in the presence of recombinant PD-L1 to mimic TME inhibitory signaling. Simultaneously, the cells were co-incubated with a library of nanobody-displaying bacteriophage. The top 10% of live T cells expressing the highest levels of the activation marker CD69 were sorted via flow cytometry to capture nanobodies capable of enhancing T cell activation, independent of their binding target. Enrichment dynamics were tracked via Oxford Nanopore sequencing. Individual phage clones were subsequently amplified and re-tested for both binding and functional modulation within the same assay.\nNew Data: We initiated the screen using a library with confirmed in vivo efficacy, verifying that this activity translated to detectable baseline modulation in our ex vivo model to ensure the presence of enrichable candidates. From this validated starting point, we performed four rounds of biopanning and sorting for increased CD69 expression. We isolated individual clones that, based on amplicon sequencing, collectively represented 25% of the starting library population. These dominant clones were individually tested for activity. Notably, clone 9-1-12 exhibited significant binding to CD8 T cells compared to controls. Critically, this binding was functionally linked to activation: the specific population of T cells bound by the nanobody displayed a significantly increased frequency of CD69 positivity despite the presence of PD-L1 inhibition. This demonstrates the feasibility of recovering a functional modulator solely through phenotypic selection.\nConclusions: Our findings provide evidence that INSPIRE-seq can select and enrich for nanobodies that alter cell function in a target-agnostic manner. This supports our central hypothesis that phenotypic screening can identify immunomodulators without prior antigen knowledge, offering a novel pipeline to uncover therapeutic candidates that overcome TME immunosuppression.", "source_company": "UTSW", "source_org_type": "未知", "row_number": 546, "target_meta": "not available", "MOA_meta": "单域抗体"}, {"drug_name": "humanized nanobody targeting KLK2", "company": "University of Minnesota Medical School", "org_type": "大学", "target": "KLK2", "modality": "nanobody", "importance_level": "中", "total_score": 51.5, "institution_score": 35, "track_score": 75, "milestone_score": 45, "field_heat_score": 65, "bonus_score": 4, "brief_reason": "针对前列腺癌特异性靶点KLK2的人源化纳米抗体，采用AI驱动de novo设计，可用于T/NK cell engager和CAR-T/NK。大学早期概念验证阶段，AI+新型nanobody平台有一定创新亮点，但机构与临床里程碑较弱。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3529", "id": "YVXM_5wBX1NQZOEH-LK6", "source_drug_name": "humanized nanobody targeting KLK2", "title": "AI-driven de novo design of humanized nanobodies targeting KLK2 for prostate cancer immunotherapy", "abstract_text": "Conventional monoclonal antibodies (mAbs) are widely used in cancer therapy but are limited by large size (~150 kDa), structural complexity, and high production costs, motivating the development of alternative antibody formats. Single-chain variable fragments (scFvs), derived from mAbs, retain antigen-binding specificity and affinity while offering a smaller molecular size (~25 kDa), enabling applications such as chimeric antigen receptor (CAR)-T/NK cells and/or bispecific T/NK cell engagers (BiTEs or NKCEs) for immunotherapy. However, scFvs face challenges including structural instability, linker-dependent functionality, and aggregation-prone hydrophobic residues, which limit their therapeutic efficacy. In contrast, single-domain antibodies (sdAbs), derived from the variable antigen-binding domain of heavy-chain-only antibodies (VHHs) and commonly known as nanobodies (~15 kDa), overcome these limitations. Importantly, nanobodies can access cryptic or conformational epitopes—such as deep cavities that are inaccessible to conventional mAbs or scFvs—providing a stable, highly versatile, and clinically attractive biotherapeutic modality for cancer immunotherapy. Traditional methods to develop nanobodies rely on targeting protein-immunized camelids or high-throughput experimental nanobody display systems, including bacteria, phage, ribosome, or yeast display. These approaches are time-consuming, labor-intensive, camelid-derived (with potential immunogenicity), and restricted in library diversity. Moreover, affinity maturation and specificity optimization require multiple iterative rounds of experimental selection—often taking months to years—and may still fail to produce high-affinity nanobodies against difficult targets. To address these challenges, we developed and integrated multiple artificial intelligence (AI) platforms for target-guided humanized nanobody backbone design, soluble protein sequence generation, and enhanced target-nanobody complex prediction and screening. These platforms enable de novo, conformational epitope-based nanobody design, generating diverse, high-affinity, and highly specific candidates entirely in silico, with experimental validation achievable within weeks to months depending on the target. As a proof-of-principle, we have applied our AI platforms to design humanized nanobodies targeting kallikrein-related peptidase 2 (KLK2), a clinically validated, prostate cancer-specific cell surface protein, and are experimentally engineering the top-designed candidates into T/NK cell engagers and CAR-T/NK cells to evaluate their ability to eliminate KLK2-expressing prostate cancer cells.", "source_company": "University of Minnesota Medical School", "source_org_type": "大学", "row_number": 547, "target_meta": "KLK2", "MOA_meta": "单域抗体"}, {"drug_name": "p27-targeting small molecule", "company": "Concarlo Therapeutics", "org_type": "公司", "target": "p27", "modality": "inhibitor", "importance_level": "中", "total_score": 51.5, "institution_score": 45, "track_score": 75, "milestone_score": 35, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "药物通过靶向p27实现对CDK2/4/6的协同间接抑制，针对CDK4/6抑制剂耐药乳腺癌，具有新机制潜力。Concarlo为preclinical阶段小公司，赛道涉及CDK耐药热门但非顶级热门靶点，整体开发早期导致分数中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11455", "id": "xVXM_5wBX1NQZOEH-LK6", "source_drug_name": "p27-targeting small molecule", "title": "Small-molecule targeting of p27 enables coordinated CDK2/4/6 inhibition in CDK4/6i-resistant breast cancer", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Concarlo Therapeutics", "source_org_type": "公司", "row_number": 612, "target_meta": "TMED7,CDKN1B", "MOA_meta": "抑制剂"}, {"drug_name": "ViRTuE-LTP", "company": "未知", "org_type": "未知", "target": "未披露", "modality": "live biotherapeutic", "importance_level": "中", "total_score": 51.5, "institution_score": 30, "track_score": 75, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "ViRTuE-LTP为基于粪菌移植验证的RT增强型活体生物制剂，通过调控肠道菌群及代谢物（如降低SCFA）改善NSCLC放疗免疫效应，机制新颖且具可转化性；机构未知导致分数偏低，但活体生物制剂+放疗增敏赛道热度较高且已完成临床pilot+动物验证。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9494", "id": "ZFXM_5wBX1NQZOEH-LO6", "source_drug_name": "ViRTuE-LTP", "title": "Gut-targeted antibiotic modulation enhances radiotherapy response in NSCLC and uncovers epigenetic and microbiome-driven immune programs enabling live biotherapeutic design", "abstract_text": "Stereotactic body radiotherapy (SBRT) can induce immunogenic cell death and stimulate systemic antitumor immunity, yet clinical responses remain heterogeneous. Preclinical studies indicate that the gut microbiome modulates host immune tone and influences responsiveness to therapy. We previously demonstrated in lung cancer and melanoma models that oral vancomycin enhances the antitumor effects of radiotherapy by depleting Gram-positive taxa responsible for generating short-chain fatty acids (SCFAs) and other immunosuppressive metabolites. Based on these observations, we conducted the first randomized clinical pilot study evaluating SBRT with or without oral vancomycin in early-stage non-small cell lung cancer (NSCLC). Patients eligible for SBRT (50 Gy in 4-5 fractions) were randomized to SBRT alone or SBRT plus vancomycin administered for one week before and five weeks after SBRT. Serial stool, serum, and PBMC samples were collected at five predefined time points. Primary endpoints were feasibility and safety, while immune activation; progression-free survival; overall survival; and changes in stool SCFAs served as exploratory endpoints. Seventeen patients enrolled; seven completed vancomycin treatment. No grade ≥3 toxicities occurred, and gastrointestinal symptoms were the most frequent adverse events. Cancer recurrence occurred in four patients, three of whom received SBRT alone, with nodal failure as the predominant pattern. Microbiome sequencing revealed marked reductions in specific Gram-positive taxa and compensatory expansion of vancomycin-resistant organisms. Stool metabolomics demonstrated substantial decreases in SCFAs in the vancomycin arm. RNA sequencing of PBMCs showed robust enrichment of antigen-processing and presentation pathways, together with interferon-related immune activation signatures. To extend these findings, we performed epigenetic and functional validation studies. PBMC chromatin profiling confirmed increased accessibility at interferon- and antigen-presentation-associated regulatory regions in vancomycin-treated subjects. Guided by these results, we evaluated whether the vancomycin effect was microbiome-transferable by engrafting stool from SBRT-alone or SBRT+vancomycin patients into antibiotic-conditioned mice. Mice colonized with post-vancomycin human stool reproduced the enhanced radiotherapy response, demonstrating that the immune effects are mediated by the gut ecosystem. These results provide the mechanistic rationale for developing ViRTuE-LTP (RT-enhancing live biotherapeutic) candidates. Consistent with the clinical observations, a defined 3-strain ViRTuE-LTP consortium enhanced APC activation and potentiated RT responsiveness in complementary murine studies.", "source_company": "", "source_org_type": "未知", "row_number": 718, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "1A-116", "company": "UCA Instituto de Investigaciones Biomédicas", "org_type": "研究机构", "target": "Rac1", "modality": "inhibitor", "importance_level": "中", "total_score": 51.5, "institution_score": 35, "track_score": 65, "milestone_score": 65, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "1A-116为Rac1小分子抑制剂，在T细胞淋巴瘤细胞系和同系小鼠模型中显示显著抗肿瘤活性，IC50 20-250 µM并实现肿瘤生长80%抑制，但Rac1作为靶点在肿瘤领域非最热门。机构为阿根廷大学研究机构非头部药企，得分受限。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4700", "id": "blXM_5wBX1NQZOEH-LO6", "source_drug_name": "1A-116", "title": "Targeting Rac1 as a therapeutic vulnerability in T-cell lymphomas", "abstract_text": "T-cell lymphomas (TCL) are aggressive and heterogeneous neoplasms with limited therapeutic options and poor prognosis, underscoring the need for novel molecular targets. Here, we investigated Rac1, a Rho GTPase that regulates cytoskeletal dynamics, migration, and survival pathways, as a potential therapeutic vulnerability in TCL. Its central role in these tumor-promoting processes suggests that Rac1 inhibition could represent an innovative strategy to limit lymphoma growth and dissemination. We first evaluated the anti-lymphoma activity of the pharmacological Rac1 inhibitor 1A-116 in a panel of TCL cell lines (EL4, CUTLL1, OCI-Ly12, OCI-Ly13.2, HuT78, MJ, Karpas299). Cell viability was assessed by luminescence assay, and apoptosis by caspase-3/7 activity after 48 h of treatment. We found that 1A-116 markedly reduced cell viability in all models (p<0.01), with IC₅₀ values ranging from 20 to 250 µM, and induced a 60-200% increase in caspase activity (p<0.05). Basal Rac1 expression was elevated compared with healthy murine lymph node controls, showing a 30-60% increase across cell lines (p<0.05). Consistently, basal phosphorylated PAK 1-3 levels, an indicator of Rac1 pathway activation, were significantly higher in most lines, except for HuT78 and Karpas299, the most resistant cells to Rac1 inhibition. To further validate the therapeutic potential of Rac1 targeting, we used a syngeneic mouse model bearing subcutaneous EL4 tumors. Daily intraperitoneal injections of 1A-116 (20 mg/kg) for nine consecutive days significantly reduced tumor growth, showing an average 80% reduction in tumor area under the curve (p=0.0071) and a 79% decrease in final tumor volume (p=0.0175), with no overt signs of toxicity. Finally, analysis of three independent TCL RNA-seq datasets (GSE113113, GSE168508, GSE58445) showed that increased expression of Rac1 activators such as VAV1 and TIAM2, and downstream effectors such as PAK2 and GSK3 correlates with advanced disease and poorer survival (p<0.05). In line with these findings, Rac1 immunostaining in 14 TCL biopsies revealed positive expression in all cases, underscoring the clinical relevance of Rac1 signaling in TCL. Together, these results identify Rac1 as a key molecular driver in TCL and establish its pharmacological inhibition as a promising and translationally relevant therapeutic strategy. Our study provides a strong rationale for further evaluation of Rac1 inhibitors, either alone or in combination regimens, to improve treatment outcomes in patients with T-cell lymphomas. Overall, these data identify Rac1 signaling as a promising target that may expand the currently limited treatment landscape for these aggressive malignancies.", "source_company": "UCA Instituto de Investigaciones Biomédicas", "source_org_type": "研究机构", "row_number": 723, "target_meta": "RAC1", "MOA_meta": "抑制剂"}, {"drug_name": "AAV-DJ", "company": "Azenta Life Sciences", "org_type": "公司", "target": "未披露", "modality": "other", "importance_level": "中", "total_score": 51.5, "institution_score": 45, "track_score": 75, "milestone_score": 40, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "AAV-DJ为工程化腺相关病毒载体，主要聚焦ITR稳定性优化以提升癌症基因治疗递送效率，未明确具体治疗靶点或转基因。机构为生命科学服务提供商而非头部药企，赛道为热门AAV基因治疗但本研究属方法学优化而非药物开发里程碑。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10422", "id": "vVXM_5wBX1NQZOEH-LO6", "source_drug_name": "AAV-DJ", "title": "Engineering robust AAV vectors: Addressing ITR instability for effective cancer gene therapy", "abstract_text": "Introduction: Cancer remains one of the most challenging diseases to treat due to the complexity of tumor biology and barriers to effective drug delivery. Gene therapy using adeno-associated viruses (AAVs) offers a promising approach for oncology, particularly with the development of engineered capsids such as AAV-DJ, which demonstrate enhanced tissue penetration and targeted gene expression in tumor microenvironments. Importantly, AAV-based strategies are also being explored in neuro-oncology, where capsid variants capable of crossing the blood-brain barrier provide new opportunities for treating aggressive brain tumors such as glioblastoma. The AAV genome consists of a therapeutic transgene flanked by 145 bp inverted terminal repeats (ITRs), which are prone to mutations and deletions but also essential for viral packaging. While capsid engineering has improved tumor targeting and systemic delivery, ITR instability remains a critical challenge for consistent therapeutic outcomes.\nMethods: In this study, we evaluated the impact of five common ITR mutations on vector integrity and performance. HEK293T cells were co-transfected with transfer, Rep/Cap (AAV-DJ), and helper plasmids for viral packaging. ITR mutations were confirmed via Sanger sequencing, and purified vectors were assessed for viral titers using qPCR and transduction efficiency via GFP fluorescence microscopy. Mutant ITRs were subsequently repaired to wild-type sequences to compare recovery of function. To model therapeutic relevance, AAV vectors were tested in tumor-bearing mice using immunofluorescence markers to assess transgene expression within cancerous tissues.\nResults: Even minor ITR alterations, such as single base pair deletions, demonstrated significantly reduced viral titers and transduction efficiency, with more pronounced effects in constructs carrying large therapeutic cassettes. Although mutant vectors retained some tumor-targeting capability, wild-type ITR constructs achieved the highest efficiency.\nConclusion: This work underscores the critical role of ITR integrity in AAV-based oncology applications, including neuro-oncology. Even small sequence disruptions can compromise vector potency, highlighting the need for rigorous quality control during vector design and production. These findings inform the development of robust AAV platforms for cancer gene therapy, ensuring optimal delivery and therapeutic impact.", "source_company": "Azenta Life Sciences", "source_org_type": "公司", "row_number": 781, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "EYA4 inhibitor", "company": "The University of Texas Health Science Center at San Antonio", "org_type": "大学", "target": "EYA4", "modality": "inhibitor", "importance_level": "中", "total_score": 51.5, "institution_score": 35, "track_score": 65, "milestone_score": 55, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "靶向EYA4酪氨酸磷酸酶活性及ssDNA结合功能的小分子抑制剂，可破坏TNBC中HR修复导致DNA损伤积累和肿瘤生长抑制。机构为大学非商业实体得分较低，但新型DNA修复靶点机制在HRD+癌症中有潜力，preclinical数据显示清晰细胞水平效应和广谱性故整体中等重要性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10477", "id": "9lXM_5wBX1NQZOEH-LO6", "source_drug_name": "EYA4 inhibitor", "title": "The protein phosphatase EYA4 is a druggable target for the treatment of breast cancer", "abstract_text": "Eyes Absent Homolog 4 (EYA4) is a dual-specificity phosphatase re-expressed in triple-negative breast cancer (TNBC) through methylation of repressive transcription factor marks. Its overexpression correlates with advanced disease and promotes genomic instability by deregulating Rad51-mediated homologous recombination (HR) and non-homologous end joining (NHEJ), throughout the cell cycle. Here, we characterize a novel property of EYA4: its ability to bind single-stranded DNA (ssDNA), and present a small-molecule inhibitor that abolishes its tyrosine phosphatase activity, possibly through the weakening of the DNA binding. Using a combination of chimeric EYA4 fragments and mutants, mobility shift assays, and biophysical methods including nuclear magnetic resonance (NMR) spectroscopy and microscale thermophoresis (MST), we mapped the DNA-binding interface and identified key residues mediating this interaction. ssDNA binding was found to stimulate the tyrosine phosphatase activity of EYA4, and our small-molecule inhibitor disrupts the phosphatase activity with an IC50 of 1 µM, indirectly suppressing enzymatic function. Functional assays, including homologous recombination reporter systems, immunofluorescence for DNA damage markers, MTT viability assays, and live-cell imaging using the Incucyte system (Essen), showed that EYA4 inhibition impairs HR, leads to DNA double-strand break accumulation, reduces proliferation, and increases apoptosis in MDA-MB-231 TNBC and TKCC PDAC models at concentrations of 1-5 µM. Fluorescent Ubiquitination-based Cell Cycle Indicator (FUCCI) imaging further revealed cell cycle defects, including mitotic failure and chromosomal segregation errors, consistent with disrupted repair during replication. Testing conducted on large panels of patient derived cell lines with the EYA4 inhibitor alone and in combination with standard of care demonstrated broader therapeutic relevance. These findings support targeting EYA4’s DNA-binding function as a valid strategy to suppress tumor growth and enhance the efficacy of DNA-damaging therapies in HR-deficient (HRD+) cancers.", "source_company": "The University of Texas Health Science Center at San Antonio", "source_org_type": "大学", "row_number": 823, "target_meta": "EYA4", "MOA_meta": "抑制剂"}, {"drug_name": "anti-CSF1R antibody", "company": "UT MD Anderson Cancer Center", "org_type": "医院", "target": "CSF1R", "modality": "antibody", "importance_level": "中", "total_score": 51.5, "institution_score": 30, "track_score": 75, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "anti-CSF1R antibody靶向CSF1R阻断CSF1/CSF1R轴以改善RBM10缺失KRAS突变NSCLC的免疫抑制微环境并逆转PD-1耐药。机构为顶级医院而非药企导致机构分较低，但myeloid靶向+免疫协同在热门赛道有较强preclinical协同数据，综合重要性中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1329", "id": "VFXM_5wBX1NQZOEH-LS6", "source_drug_name": "anti-CSF1R antibody", "title": "RBM10 loss promotes KRAS-mutant non-small cell lung cancer immune tolerance and PD-1 inhibitor resistance via a non-canonical STING/ NF-κB axis", "abstract_text": "Loss-of-function mutations in RBM10, encoding a protein involved in the regulation of alternative splicing, are observed in ~10% of non-squamous NSCLC and are enriched in tumors harboring activating mutations in KRAS, yet little is known about how RBM10 inactivation promotes lung cancer progression or influences response to standard-of-care systemic therapies. Here, we elucidated the cooperative interplay between oncogenic KRAS activation and RBM10 loss in NSCLC pathogenesis using a novel genetically engineered mouse model with conditional RBM10 deletion, as well as multiple isogenic syngeneic allograft models that faithfully recapitulate RBM10-deficient human lung adenocarcinoma. We found that loss of RBM10 accelerates KRAS-mutant NSCLC progression by fostering the establishment of a tolerogenic, myeloid cell-rich tumor immune microenvironment (TIME). Mechanistically, RBM10 loss promoted R-loop accumulation and chronic DNA damage signaling that engaged the non-canonical TRAF6-STING pathway in a cGAS-independent manner, leading to sustained NF-κB activation. We identified several cytokines and chemokines, canonical targets of NF-κB signaling, such as IL-1β, IL-6, TNFα, and MCP-1, that were upregulated in RBM10-deficient cells. This NF-κB-driven secretome promoted the development of an inflamed, TIME characterized by accumulation of suppressive myeloid cell subsets - most notably monocytes and M2-like macrophages, and dysfunctional tumor infiltrating lymphocytes (TILs) thereby fostering immune evasion and cancer progression. Furthermore, we exploited the RNA-seq database of human lung adenocarcinoma from The Cancer Genome Atlas (TCGA) and again found that RBM10 loss was significantly linked to impaired DNA damage response, upregulation of the HALLMARK_TNFA_SIGNALING_VIA_NF-κB, and enrichment of M2-macrophages. Strikingly, targeting the CSF1/CSF1R axis with an anti-CSF1R antibody significantly curtailed the growth of RBM10-deficient tumors in syngeneic immunocompetent models and synergized with anti-PD-1 therapy to promote tumor regression. In conclusion, our findings uncovered a novel critical role of RBM10 inactivation in driving immune escape and PD-1 inhibitor resistance in KRAS-mutant NSCLC and suggest a potential therapeutic strategy by co-targeting suppressive myeloid cells to improve cancer immunotherapy for patients bearing KRAS;RBM10 co-mutated tumors.", "source_company": "UT MD Anderson Cancer Center", "source_org_type": "医院", "row_number": 891, "target_meta": "CSF-1R", "MOA_meta": "抗体"}, {"drug_name": "OV-x44", "company": "Augusta University", "org_type": "大学", "target": "CD44", "modality": "oncolytic virus", "importance_level": "中", "total_score": 51.5, "institution_score": 35, "track_score": 75, "milestone_score": 45, "field_heat_score": 65, "bonus_score": 3, "brief_reason": "OV-x44为编码分泌型CD44胞外部分的溶瘤HSV，通过阻断CD44介导的细胞-ECM相互作用抑制肿瘤细胞STING激活并增强病毒复制，同时刺激TME内免疫反应。大学机构得分较低但溶瘤病毒+新型CD44调控机制具有一定创新性和免疫刺激潜力，故整体处于中等重要性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9586", "id": "gZ7ECZ0BZznHJdntvNYd", "source_drug_name": "OV-x44", "title": "Blockade of cell-ECM interaction with an oncolytic virus suppresses tumoral STING activation while inducing antitumor immunity", "abstract_text": "Oncolytic HSV (oHSV) therapy is an emerging immunotherapeutic modality currently approved for melanoma in USA and EU and conditionally approved for recurrent brain tumors in Japan. Several clinical trials are investigating the utility of this approach in patients. To investigate ways to improve its therapeutic index, we analyzed the transcriptomic changes in patients with recurrent brain tumor pre and post CAN-3110 treatment (NCT03152318). Gene set enrichment analysis showed significant enrichment in the pathways of extracellular matrix (ECM) interactions and glycosaminoglycan (GAG) synthesis post virotherapy. CD44, a cell surface receptor, plays a crucial role in cell-cell and cell-ECM interactions. Apart from engaging with ECM components like hyaluronic acid (HA), collagens, fibronectin, osteopontin, matrix metalloproteinases (MMPs), etc., it also partners with several cell surface receptors like growth factor receptor family and integrins to guide cellular responses to ECM and growth factor stimulation. Here we investigated the role of CD44 signaling in regulation of both anti-viral innate immunity and anticancer adaptive immunity by creating an oHSV that encodes for the secreted extracellular portion of CD44 (OV-x44). Our results indicated that OV-x44 destabilized xCT and disrupted cellular redox homeostasis. Increased oxidative stress resulted in tumor selective STING carbonylation, and reduced TBK1 activation, thereby enhancing virus replication. On the contrary, single-cell RNA sequencing uncovered enhanced innate immune responses in immune cells with TLR7 driven activation in T cells in the tumor microenvironment (TME). To our knowledge, this is the first report to describe an oHSV that can inhibit innate intracellular anti-viral immunity in tumor cells and can also stimulate innate immune responses in the TME to guide antitumor immunity. Collectively, this study uncovers the significance of OV-x44 as a potent immune stimulating anticancer therapeutic.", "source_company": "Augusta University", "source_org_type": "大学", "row_number": 1004, "target_meta": "CD44", "MOA_meta": "溶瘤病毒"}, {"drug_name": "SSHELs", "company": "NIH-NCI", "org_type": "政府机构", "target": "HER2", "modality": "other", "importance_level": "中", "total_score": 51.5, "institution_score": 35, "track_score": 75, "milestone_score": 45, "field_heat_score": 65, "bonus_score": 2, "brief_reason": "SSHELs为新型合成细菌孢子样颗粒，靶向HER2阳性细胞实现mRNA/siRNA特异递送，属于靶向RNA递送平台。政府机构背景限制机构分，递送技术有一定创新但仍处早期研究阶段，总分处于中等水平。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6394", "id": "VJ7M_5wBZznHJdnt_W3O", "source_drug_name": "SSHELs", "title": "Targeted delivery of RNA using synthetic bacterial spores", "abstract_text": "Background: RNA therapy holds increasing promise for the treatment of various diseases. Delivering RNA, however, typically requires encapsulation in lipid nanoparticles, and a limitation of this technology is achieving tissue specificity beyond the liver and kidneys. We previously reported synthetic bacterial spore-like particles, termed “SSHELs,” for targeted cargo delivery [1]. SSHELs, composed of defined, biocompatible materials, were shown to specifically bind to HER2-positive cancer cells and accumulate in tumors [2]. This study explores whether SSHELs can deliver RNA to tissue-specific locations, focusing on HER2-positive cells.\nMethods: The experimental approach involved protein purification, SSHEL assembly, mRNA and siRNA loading, and assessing RNA delivery specificity via confocal microscopy and flow cytometry. In vitro and in vivo assays were conducted to assess the production of EGFP and luciferase in target cells. Experimental models included cell cultures and mice.\nResults: By decorating SSHELs with anti-HER2 affibodies and modulating lipid composition, we achieved specific mRNA and siRNA delivery to HER2-positive cells, resulting in selective protein induction or silencing. Loading SSHELs with RNA was highly efficient (~95%), yielding thousands of transcripts per particle. In further investigations, we observed a distinctive feature of SSHELs made with DOTAP: they did not elicit or suppress inflammatory cytokine production (e.g., TNF-α, IL-6). This characteristic is noteworthy, as it suggests the biocompatibility and immunologically inert nature of SSHELs formulated with DOTAP. Ongoing in vivo experiments are assessing the efficacy of mRNA-loaded SSHELs in delivering cargo to HER2-positive tumors.\nConclusions: SSHELs represent a novel approach in RNA therapeutics due to their unique characteristics. These particles, which mimic the structure of bacterial spores, provide a biocompatible and versatile platform for the targeted delivery of myriad therapeutics, such as small molecules, peptides, and RNAs.\nReferences:\n Wu, I.-L., et al. (2015). A versatile nano display platform from bacterial spore coat proteins. Nature Communications, 6, 6777. Kong, M., D’Atri, D., et al. (2023). Cell-specific cargo delivery using synthetic bacterial spores. Cell Reports, 42(1), 111955.", "source_company": "NIH-NCI", "source_org_type": "政府机构", "row_number": 1007, "target_meta": "HER2", "MOA_meta": "其他"}, {"drug_name": "Brusatol", "company": "Hong Kong Baptist University", "org_type": "大学", "target": "NRF2", "modality": "inhibitor", "importance_level": "中", "total_score": 51.5, "institution_score": 30, "track_score": 75, "milestone_score": 50, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "Brusatol为NRF2抑制剂，通过抑制NRF2调控的聚胺和谷胱甘肽代谢增强化疗在KRAS突变结直肠癌中的疗效。机构为大学得分较低，赛道涉及NRF2+铁死亡+KRAS相关代谢重编程有一定热度，处于preclinical组合研究阶段，整体中等重要性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9148", "id": "lp7M_5wBZznHJdnt_W3O", "source_drug_name": "Brusatol", "title": "Targeting NRF2-regulated polyamine and glutathione metabolism enhances chemotherapy efficacy in colorectal cancer based on KRAS status", "abstract_text": "Metabolic reprogramming is a hallmark of colorectal cancer and is strongly influenced by oncogenic KRAS mutations, which contributes to reduced drug responsiveness and poor clinical outcomes. Inducing ferroptosis—a form of iron-dependent, lipid peroxidation-driven cell death—has emerged as a promising strategy to augment chemotherapy response by disrupting this adaptive metabolic state. However, the interplay between KRAS-specific metabolism and ferroptosis-induced drug sensitivity remains incompletely understood and could enable precision therapeutic interventions. In our study, we integrated public datasets and in vitro experiments to investigate the drug combination effect and how the metabolism will be altered. We first utilized drug sensitivity data from CRC cell lines, and we found that drug response varied by KRAS status and engaged distinct ferroptotic dependencies: KRAS-mutant cells showed increased reliance on iron-handling genes (FTH1, FTL, SLC11A2), whereas KRAS wild-type cells were more vulnerable to disruption of GPX4-mediated antioxidant defense. Given that NRF2 coordinates ferroptosis through both iron homeostasis and antioxidant responses, pharmacologic inhibition of NRF2 using Brusatol across four CRC cell lines (representing wild type, KRAS G12D, and KRAS G13D) markedly enhanced chemotherapy efficacy, with the strongest effect observed in KRAS G12D lines, followed by wild-type cells. Regarding non-targeted metabolomics analysis, co-treatment with Brusatol and Oxaliplatin or 5-Fluorouracil rendered dysregulated pathways that fuel cancer growth and progression, including methionine cycle, nucleotide synthesis as well as energy metabolism only in wild-type cells and KRASG12D mutant which accounted for improved inhibitory effect. Moreover, distinctive alterations depending on KRAS mutation were observed under this combination therapy, manifesting KRAS mutants (comprising KRASG12D and KRASG13D) demonstrated an blockage of polyamine catabolism with extremely decreased acetylspermine, whereas wild-type cells suffered elevated oxidative stress with severe GSH exhaustion and GSH/GSSG ratio reduction. In light of clinical unavailability of Brusatol, we successfully repositioned several clinically viable antineoplastic drugs and a panel of therapeutic agents under preclinical status for emerging tumor combat utilizing a transcriptional-based silico drug repurposing approach. Our findings highlighted NRF2 deprivation-mediated polyamine metabolism as a potential target for chemosensitivity and provided a clinically-approved therapeutic option in KRASG12D CRC, brightening the path for targeted therapy and translation medicine.", "source_company": "Hong Kong Baptist University", "source_org_type": "大学", "row_number": 1051, "target_meta": "Nrf2", "MOA_meta": "抑制剂"}, {"drug_name": "PD-1 axis inhibitor", "company": "Yale School of Medicine", "org_type": "大学", "target": "PD-1 axis", "modality": "inhibitor", "importance_level": "中", "total_score": 51.5, "institution_score": 35, "track_score": 85, "milestone_score": 40, "field_heat_score": 80, "bonus_score": 0, "brief_reason": "PD-1 axis inhibitor为成熟的免疫检查点抑制剂，靶向PD-1/PD-L1通路，在mNSCLC中已有广泛验证。研究由大学机构开展，聚焦生物标志物而非新药开发，临床里程碑价值有限，故综合重要性中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9525", "id": "v57M_5wBZznHJdnt_W3O", "source_drug_name": "PD-1 axis inhibitor", "title": "Intratumoral effector T-cells and macrophages underlie prolonged survival after PD-1 axis blockade in metastatic non-small cell lung cancer (mNSCLC)", "abstract_text": "Background: Although PD-1 axis inhibitors have improved outcomes in patients with mNSCLC, only a subset of patients derives long-term benefit. Most studies assessing determinants of sensitivity have relied on short-term endpoints such as response, potentially overlooking biological features underlying durable tumor control. We hypothesized that patients achieving prolonged response after PD-1 axis blockade exhibit distinct tumor microenvironment (TME) features compared with those with primary resistance or limited response.\nMethods: We assembled a retrospective cohort of bulk whole-transcriptome data from 342 pretreatment tumor samples from patients with mNSCLC treated with PD-1 axis blockade alone or in combination with anti-CTLA-4 therapy from Yale (n=31), Stand Up To Cancer (n=73), and Samsung Medical Center (n=278). Patients were classified as having primary progression (PP; PFS <3 mo; n=200), non-exceptional response (NER; PFS 6-36 mo; n=116), and prolonged survival (PS; PFS >36 mo; n=26). After batch correction, differential expression (limma) and CIBERSORT were used to identify genes and immune cells associated with PS. Single-cell RNA sequencing from a publicly-available lung cancer immune cell atlas (n=234) was used to refine immune cell signatures and assess their association with outcomes via ssGSEA. Spatial proteomics (Phenocycler-Fusion) performed on baseline samples from patients treated with PD-1 axis blockade (n=55; PP=21, NER=26, PS=8) at Yale and the University of Queensland was used for validation.\nResults: Tumors from PP, NER, and PS demonstrated a stepwise increase in HLA class I antigen-presentation machinery (APM) transcripts (PSMB9, ERAP2), memory T-cell markers (CXCR6), and CD8⁺ T-cell infiltration. PD-L1 expression was markedly higher in NER than PP, but similar between NER and PS. The most significantly enriched genes in PS relative to NER were macrophage-related, with higher absolute M1 (Cliff’s δ=0.34, p=0.007) and M2 (δ=0.29, p=0.023) tumor-associated macrophage (TAM) scores. This difference was not observed between NER and PP. Four percent of patients with low (≤ median) calculated CD8⁺ T-cell and TAM levels were PS, compared with 15% of those with high CD8⁺/TAM levels (odds ratio=4.5, p=0.0083). Single-cell analysis identified 15 TAM subsets, several enriched in PS but none in PP. Spatial proteomics confirmed an increase in the proportion of stromal TAMs in PS (PS vs NER: δ=0.62, p=0.0079; PS vs PP: δ=0.58, p=0.016) and revealed a stepwise decrease in the proportion SMA⁺ fibroblasts across clinical benefit groups.\nConclusion: Prolonged survival after PD-1 blockade in mNSCLC is associated with distinct TME features including increased expression of APM components, and increased CD8 T-cells and TAMs. These insights may inform the development of predictive biomarkers and novel therapeutic strategies.", "source_company": "Yale School of Medicine", "source_org_type": "大学", "row_number": 1089, "target_meta": "PD1", "MOA_meta": "抑制剂"}, {"drug_name": "CD276-targeting chemically self-assembled nanorings", "company": "Houston Methodist Research Institute", "org_type": "研究机构", "target": "CD276", "modality": "other", "importance_level": "中", "total_score": 51.5, "institution_score": 35, "track_score": 75, "milestone_score": 45, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "药物为靶向CD276（B7-H3）的化学自组装纳米环，在SHH型髓母细胞瘤模型中显示出模拟Yap1缺失的男性偏向性生存优势并增强CD8+ T细胞抗肿瘤应答。机构为研究机构得分较低，但靶点为热门免疫检查点且机制创新性较强，preclinical阶段有明确体内疗效证据故整体重要性中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1755", "id": "1J7M_5wBZznHJdnt_W3O", "source_drug_name": "CD276-targeting chemically self-assembled nanorings", "title": "Targeting Yap1-B7-H3 signaling stimulates CD8⁺ anti-tumor response preferentially in male SHH medulloblastoma", "abstract_text": "Sex-biased mechanisms in cancer remain poorly understood. We recently reported an unexpected sex-biased function of Yap1, an oncogene dysregulated in many human cancers, in murine models of SHH medulloblastoma (MB). Yap1 deletion significantly extends survival preferentially in male animals and enhances immune infiltration, in part by attenuating the expression of the immune checkpoint molecule Cd276 (B7-H3) in MB cells. These findings are clinically relevant because male patients with MB, the most common pediatric brain malignancy, exhibit worse survival and a higher incidence.\nHere, we investigate the sex-specific consequences of Yap1 loss and evaluate therapeutic targeting of CD276 using systemically administered CD276-targeting chemically self-assembled nanorings (CD276-CSANs).\nExtensive characterization of the immune microenvironment in Yap1-deleted male and female tumors, conducted via single-cell RNA sequencing and high-parameter flow cytometry, revealed a significant increase in CD8+ T cells exhibiting cytotoxic properties in males, but not in females. In contrast, Yap1-deleted females had higher numbers of exhausted CD8+ T cells and regulatory T cells. Further, in vivo CD8 T cell depletion abolished the survival advantage seen in Yap1-deleted male MB, confirming the functional importance of these cells.\nT-cell proliferation assays demonstrated that in male MB cells, targeting either Yap1 or CD276 restored T-cell activation. In contrast, females, which have higher baseline CD276 expression, required both Yap1 deletion and CD276 blockade/deletion to achieve similar activation. Consistently, CD276 blockade with CD276-CSANs phenocopied the male-biased survival advantage of Yap1 deletion and increased CD8+ T-cell infiltration in vivo.\nOverall, these findings reveal that Yap1 promotes male-biased MB progression via Cd276-mediated CD8+ T cell suppression, resulting in immune evasion and highlighting CD276 as a promising therapeutic target for improving male MB prognosis.\n*contributed equally", "source_company": "Houston Methodist Research Institute", "source_org_type": "研究机构", "row_number": 1103, "target_meta": "CD276", "MOA_meta": "其他"}, {"drug_name": "anti-PD-1", "company": "European Institute of Oncology", "org_type": "研究机构", "target": "PD-1", "modality": "inhibitor", "importance_level": "中", "total_score": 51.5, "institution_score": 35, "track_score": 75, "milestone_score": 45, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "anti-PD-1为PD-1抑制剂，在TNBC模型中联合间歇环磷酰胺+长春瑞滨诱导可转移T细胞介导的抗肿瘤免疫和长期记忆。机构为研究型医院而非头部药企，赛道为成熟PD-1抑制剂但机制新颖组合具一定潜力，preclinical阶段无明确临床里程碑。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5724", "id": "457M_5wBZznHJdnt_W3O", "source_drug_name": "anti-PD-1", "title": "Intermittent cyclophosphamide and vinorelbine combined with anti-PD-1 induce transferable T-cell-mediated antitumor immunity and long-term memory in TNBC mouse models", "abstract_text": "Cell-based immunotherapies offer a powerful means to harness treatment-induced antitumor immunity for durable tumor control. We previously developed a Triple-Therapy (TT) regimen combining vinorelbine-mediated activation of antigen-presenting cells (APCs) with cyclophosphamide-driven induction of TCF1⁺ stem-cell-like T cells (scTs), markedly enhancing anti-PD-1 efficacy in resistant tumor models. The TT protocol consists of three intermittent doses of vinorelbine, and cyclophosphamide administered every six days, together with five anti-PD-1 doses delivered every two days.In a Non-Hodgkin Lymphoma (NHL) model, TT not only achieved strong tumor regression but also conferred long-term immunological memory, as evidenced by protection upon tumor rechallenge. Extending these findings to triple-negative breast cancer (TNBC), TT induced comparable antitumor activity. To determine whether TT-elicited immunity could be adoptively transferred, immunocompetent BALB/c mice bearing 4T1 TNBC were treated with TT, and immune tissues—including blood, spleen, and lymph nodes—were collected and transferred into syngeneic BALB/c nude mice inoculated with the same tumor.Strikingly, transfer of peripheral blood from TT-treated donors significantly delayed tumor growth, indicating that circulating immune cells are sufficient to convey protection. In contrast, lymphocyte depletion abolished this effect. Selective ablation of CD4⁺ or CD8⁺ T cells—performed either by flow cytometric sorting or using neutralizing antibodies—also eliminated the therapeutic benefit, confirming their essential role in the transferable antitumor response.Overall, these findings demonstrate that TT induces systemic, memory-forming T-cell responses capable of mediating cell-transferable tumor control. Current work focuses on identifying the tumor antigens recognized by TT-induced T cells, with the ultimate goal of developing targeted therapeutic vaccines to extend these benefits to broader patient populations.", "source_company": "European Institute of Oncology\nEuropean Institute Of Oncology", "source_org_type": "研究机构\n医院", "row_number": 1111, "target_meta": "PD1", "MOA_meta": "抑制剂"}, {"drug_name": "anti-PD1", "company": "Sick Children's Hospital", "org_type": "医院", "target": "PD-1", "modality": "inhibitor", "importance_level": "中", "total_score": 51.5, "institution_score": 25, "track_score": 75, "milestone_score": 65, "field_heat_score": 70, "bonus_score": 2, "brief_reason": "anti-PD1为PD-1抑制剂，针对RRD突变高度突变型髓母细胞瘤显示免疫微环境炎热及单药显著疗效，包括TP53突变亚群。医院机构分较低，但热门免疫检查点靶点+临床前/临床响应数据支撑中等重要性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1763", "id": "857M_5wBZznHJdnt_W3O", "source_drug_name": "anti-PD1", "title": "Trans-species analysis of replication repair deficient medulloblastoma and response to immune checkpoint inhibition: An IRRDC report", "abstract_text": "Replication repair deficiency (RRD), caused by germline biallelic mutations in mismatch repair, leads to hypermutant brain tumour development in children and adolescents. RRD medulloblastoma have been reported but how RRD driven mutagenesis contributes to their clinical, genomic, and immune profiles is unknown. Through the International RRD Consortium, we enrolled 43 RRD medulloblastoma, analysed their exomes, methylomes, transcriptomes, and clinical outcomes. To better understand the mechanisms underlying their development and to assess preclinical responses to immunotherapy, we analyzed the histology and exomes of embryonal brain tumours developed in RRD mouse models (Nestin-Cre+/MSH2LoxP/LoxP/POLES459F/+). RRD medulloblastoma were enriched for anaplasia (61%), localised disease (77%), and harboured hypermutation and microsatellite instability, contrasting with “quiet” genomic profiles of non-RRD medulloblastoma (p<0.0001). Point mutations were frequent in POLE/POLD1 (80%), TP53 (48%), SHH pathway genes (56%) and, notably, glioma driver genes (ATRX, NF1, RB1: 50%). TP53 hotspot mutations were distinct from non-RRD medulloblastoma and occurred in trinucleotide sequence contexts which were highly mutated by RRD mutational signatures, suggesting that replication errors shape their genetic evolution. Copy-number changes were infrequent (<20%) and inversely correlated with tumour mutation burden. While most did not classify with high confidence (>0.9) on DNA methylation subtyping tools, RRD medulloblastoma shared methylation programs with SHH medulloblastoma. Non-promoter genomic regions were hypomethylated relative to non-RRD medulloblastoma, partially explaining their failure to perform in DNA methylation classifiers. Transcriptomics reflected shared expression programs between RRD and SHH medulloblastomas. RRD medulloblastoma demonstrated high CD8+ T-cell infiltration and response to anti-PD1 monotherapy, with 60% three-year progression-free survival. Outcome was worse for tumours with TP53-mutation (p=0.04). Recurrent/progressive RRD medulloblastoma treated with anti-PD1 monotherapy had prolonged survival compared those which were not (p = 0.02), including responses in TP53-mutant tumours. RRD mouse models developed tumours that mirrored histological and genetic profiles of human disease and responded to anti-PD1 monotherapy, highlighting their relevance for future preclinical studies. Human RRD medulloblastoma are distinguished by their unique spectrum of driver mutations and hypomethylation profiles, shaped by RRD mutagenesis. Mouse models recapitulate human features and offer a mechanistic model for tumorigenesis and immunotherapy responses. Importantly, immune-hot microenvironments in RRD medulloblastoma contribute to successful salvage therapy for tumours failing chemo-radiation.", "source_company": "Sick Children's Hospital\nHospital for Sick Children", "source_org_type": "医院", "row_number": 1120, "target_meta": "PD1", "MOA_meta": "抑制剂"}, {"drug_name": "Tr-ACT2", "company": "Sunstate Biosciences, LLC", "org_type": "公司", "target": "HER2", "modality": "other", "importance_level": "中", "total_score": 51, "institution_score": 40, "track_score": 65, "milestone_score": 50, "field_heat_score": 60, "bonus_score": 5, "brief_reason": "Tr-ACT2为基于单蛋白封装技术的HER2靶向抗体封装药物（AED），封装actinomycin D实现无连接子递送，在HER2+/-肿瘤中显示广谱体外/体内活性。公司为小型美国生物技术初创，SPE平台创新但非主流ADC，处于preclinical阶段且有动物模型优于对照药，整体潜力中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5492", "id": "BlXM_5wBX1NQZOEH-LK6", "source_drug_name": "Tr-ACT2", "title": "Antibody encapsulated drug: Tr-ACT2 for targeted treatments of various cancers", "abstract_text": "Purpose: HER2 is overexpressed in 15-20% of breast cancers and some other cancers, and the development of HER2-targeted therapies has revolutionized cancer treatment in past 20 years. Trastuzumab (Tr) has demonstrated efficacy in treatment of HER2+ breast cancer and advanced gastric cancer. Recently, Tr-based antibody drug conjugates (ADCs), Kadecyla and Enhertu, have emerged as a new class of anti-HER2 therapies by combining targeted antibodies with cytotoxic agents via linkers. However, ADC approach faces great challenges, such as in vivo instability, manufacturing processes, limited availability of antitumor payloads and suboptimal payload release. Therefore, smarter and more efficient designs are urgently needed.\nMethods: Our patented single protein encapsulation (SPE) platform, allowing encapsulation of small-molecule drugs by a single protein (albumins or globulins) without artificial nanoparticles and chemical modifications to drugs and proteins, has achieved great success in development of 2 drug products, SPEDOX-6 under human clinical trial (NCT0764018) and SPESN38-8 (IND #: 164346) under IND-enabling study based on albumin, which have prompted us to utilize antibody, such as Tr to encapsulate cytotoxic payload, actinomycin D (ACT, RNA polymerase inhibitor), forming antibody encapsulated drugs (AEDs). We developed Tr-ACT2 as a first-in-class AED drug, featuring each Tr molecule to encapsulate two ACT molecules without linkers. Tr-ACT2 was well characterized by UV, fluorescence, membrane dialysis, particle size distribution and molecular docking. In vitro and in vivo anticancer efficacy of Tr-ACT2 against various HER2+ & HER2- cancers were evaluated.\nResults: Tr-ACT2 has been investigated in following. In vitro cytotoxicity of Tr-ACT2 against breast cancers, HER2+ (SKBR3, JIMT1) and HER2- (BT549, MDA-MB-231) and A549 (NSCLC, HER2-) was evaluated, leading to a time-dependent and significant reduction in cell viability, induction of apoptosis and reduction of Akt activation. Tr-ACT2's cytotoxic activity appeared to be independent of HER2 expression levels. The internalization study on Tr-ACT2 demonstrated that early-stage internalization of Tr-ACT2 is HER2 dependent, but the rate of late-stage internalization of Tr-ACT2 is not limited by HER2 expression level, confirming that Tr-ACT2 could be effectively internalized into both HER2+ and HER2- cancer cells. In vivo anticancer efficacy of Tr-ACT2 at 1 mg/kg vs irinotecan at 50 mg/kg using A549 mouse model has been evaluated, showing that Tr-ACT2 was significantly more effective in suppressing growth of A549 than irinotecan.\nConclusions: We have developed the first-in-class AED nanocomplex, Tr-ACT2, as a potent anticancer agent, demonstrating that the SPE technology can be applied to antibody for encapsulating small-molecule drugs without covalent conjugation and marking a significant advancement in antibody-based therapeutics.", "source_company": "Sunstate Biosciences, LLC", "source_org_type": "公司", "row_number": 207, "target_meta": "HER2", "MOA_meta": "其他"}, {"drug_name": "6-bromoindirubin acetoxime", "company": "Brown University", "org_type": "大学", "target": "CDH5", "modality": "inhibitor", "importance_level": "中", "total_score": 51, "institution_score": 35, "track_score": 65, "milestone_score": 55, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "6-bromoindirubin acetoxime (BIA) 为广谱激酶抑制剂，主要通过下调CDH5等靶点破坏血瘤屏障完整性以增强GBM药物递送。大学机构得分较低，但GBM递送策略结合热门靶点和化疗增敏机制具有一定赛道热度和临床转化潜力。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3472", "id": "FlXM_5wBX1NQZOEH-LK6", "source_drug_name": "6-bromoindirubin acetoxime", "title": "Targeted modulation of the blood-tumor barrier enhances drug delivery and survival in glioblastoma models", "abstract_text": "Efficient drug delivery in glioblastoma (GBM) remains a major therapeutic challenge due to the restrictive properties of the blood-brain and blood-tumor barriers (BBB/BTB). We previously identified a BTB-associated transcriptional signature highlighting CDH5 (vascular endothelial cadherin) as a critical regulatory molecule highly expressed in GBM vasculature. Using bulk RNA sequencing and spatial transcriptomics, we confirmed that CDH5 and its associated genes are selectively enriched in tumor-associated endothelial cells compared with healthy brain tissue. Mechanistically, we show that the indirubin derivative 6-bromoindirubin acetoxime (BIA) significantly downregulates CDH5 and additional BTB-signature genes, including ACVRL1, ENG, and CD93. This molecular modulation disrupts endothelial barrier integrity, demonstrated by reduced trans-endothelial electrical resistance and increased dextran permeability in vitro, as well as enhanced intratumoral sodium fluorescein and cisplatin accumulation in vivo in murine GBM xenograft models. BIA treatment further augments cisplatin efficacy by increasing DNA damage, resulting in significantly extended survival compared with monotherapy. To investigate underlying mechanisms, we are assessing the effects of BIA on transcription factors involved in BBB regulation (including CREB and ERG) and on cytoskeletal dynamics. Given that BIA is a broad-spectrum kinase inhibitor with limited translational potential, we are actively evaluating FDA-approved kinase inhibitors, such as dasatinib. as clinically viable alternatives for rapid translation. Preliminary data indicate that dasatinib similarly disrupts BTB integrity and enhances chemotherapeutic penetration into GBM tumors. Ongoing studies are testing dasatinib’s preclinical efficacy, specifically its impact on drug delivery, safety, and therapeutic effectiveness. Collectively, these findings position targeted BTB modulation as a promising therapeutic strategy. Leveraging both novel agents such as BIA and repurposed FDA-approved drugs like dasatinib may significantly enhance drug delivery, improve therapeutic outcomes, and ultimately benefit patients with GBM.", "source_company": "Brown University", "source_org_type": "大学", "row_number": 287, "target_meta": "CDH5", "MOA_meta": "抑制剂"}, {"drug_name": "TMI-2", "company": "UCSF Medical Ctr.", "org_type": "医院/大学", "target": "ADAM17", "modality": "inhibitor", "importance_level": "中", "total_score": 51, "institution_score": 40, "track_score": 70, "milestone_score": 50, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "TMI-2为高特异性小分子ADAM17/TACE抑制剂，可通过抑制ADAM17活性使ICB耐药肿瘤对免疫治疗敏感，机制涉及调控肿瘤微环境和免疫细胞功能。机构为大学医院非商业药企得40分，ADAM17作为免疫治疗增敏新兴靶点赛道有一定热度得70分，前临床体内模型有效但无临床进展得50分，综合潜力中等得总分51分。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9449", "id": "FFXM_5wBX1NQZOEH-LG5", "source_drug_name": "TMI-2", "title": "Dissecting mechanisms of tumor immune checkpoint blockade resistance due to host genetic variation within Adam17", "abstract_text": "Clinical application of anti-PD-1 or anti-PDL-1 antibodies, also known as immune checkpoint blockade (ICB) therapy, has shown potential as an anti-cancer treatment. However, currently only 10 to 30 percent of cancer patients respond to ICB. Successful ICB treatment depends on a variety of factors including tumor mutation burden, cancer subtype, and patient germline genetics. Therefore, there is a clear need to understand how host genetics influences ICB clinical success to improve patient outcomes. Our laboratory primarily focuses on the study of transforming growth factor-beta (TGF-β) signaling across a variety of disease contexts. We have generated two paired congenic NIH/Ola mouse strains that harbor either NIH/Ola or C57Bl/6J across the Tgfbm3b locus on proximal chromosome mouse 12. Tgfbm3b is known to modulate TGFβ signaling and encompasses genetic variants of tumor necrosis-alpha converting enzyme (TACE, also known as ADAM17). Utilizing these congenic mice implanted with syngeneic cancer cells, we generated preliminary data suggesting that the C57 “hypoactive” allele of Adam17, with amino acid variation at D113N, I613V, correlates with better response to ICB compared to congenic mice that harbor the active NIH allele, which are resistant to ICB treatment. Considering that inheritance of hypoactive Adam17 enhances ICB response, we employed a highly specific small molecule inhibitor of TACE (TMI-2) finding that it sensitizes ICB-resistant tumors to immunotherapy across two in vivo syngeneic squamous cell carcinoma (SCC) models, suggesting that ADAM17 activity may suppress ICB efficacy. We have detailed the immune cell infiltrate on ICB sensitive and resistant mouse models, with and without ICB, using both flow cytometry and RNA sequencing techniques, and have found differences in myeloid and T cell infiltrate into the tumor microenvironment, suggesting that ADAM17 may regulate the tumor microenvironment landscape. We also have in vitro data suggesting that hypoactive variants of ADAM17 may reduce immune cell secretion of Tumor Necrosis Factor Alpha (TNFα) and TNFα induced cell death in specific immune cell types. TMI-2 is safe in humans, and this study provides support for targeting ADAM17 as a therapeutic target for patients who harbor ICB resistant cancers. The study also provides invaluable insights into the cell-type specific consequences of ADAM17 activity in tumor biology and highlights the need to consider patient genetics when applying ICB therapy.", "source_company": "UCSF\nUCSF Medical Ctr.", "source_org_type": "医院\n大学", "row_number": 324, "target_meta": "ADAM17", "MOA_meta": "抑制剂"}, {"drug_name": "a novel brain-penetrant dual ATR-mTOR inhibitor", "company": "Vancouver Prostate Centre", "org_type": "研究机构", "target": "ATR/mTOR", "modality": "inhibitor", "importance_level": "中", "total_score": 51, "institution_score": 35, "track_score": 75, "milestone_score": 45, "field_heat_score": 65, "bonus_score": 3, "brief_reason": "该药为脑穿透性双靶点ATR/mTOR抑制剂，针对PTEN缺陷肿瘤具合成致死潜力，赛道较热但仍处早期发现阶段。机构为研究机构而非药企、仅展示AI设计及计划体内数据导致总体分值中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4649", "id": "cVXM_5wBX1NQZOEH-LG5", "source_drug_name": "a novel brain-penetrant dual ATR-mTOR inhibitor", "title": "A novel brain-penetrant dual ATR-mTOR inhibitor for PTEN-deficient cancers", "abstract_text": "Ataxia telangiectasia and Rad3-related protein serine/threonine kinase (ATR), a master regulator of DNA damage repair, maintains genomic stability in cancer cells and allows cancer cells to survive with high replication stress. Inhibition of ATR thus causes genomic instability, leading to mitotic catastrophe and apoptosis. ATR inhibitors (ATRi) have been found to be particularly effective against cells harboring PTEN deficiencies due to synthetic lethality. PTEN regulates the cell cycle and interacts with key proteins like p53 and Chk1, and PTEN deficient cells show increased genomic instability due to compromised DNA repair. Inhibition of ATR in PTEN-deficient cells therefore leads to accumulation of DNA damage and cell death. PTEN loss/mutation also leads to activation of mTOR through activation of PDK1 and AKT, contributing to cell survival and growth. Therefore, simultaneous inhibition of ATR and mTOR seems rational in the context of PTEN-deficient tumor cells. PTEN deficiency can be found in up to 40% of gliomas and 63% of breast cancers, which often metastasize to the brain. Since combination treatments can be clinically difficult due to overlapping toxicities and differing pharmacokinetics, we sought to develop a CNS-penetrating dual inhibitor of ATR and mTOR for the treatment of PTEN-deficient cancers. A generative artificial intelligence platform called Enki™ was used to identify de novo molecules with optimized properties for CNS penetrance and specificity for ATR and mTOR. Enki uses a latent diffusion model to optimize many properties simultaneously within the search space, including maximal potency against the primary target, selectivity, ADMET, and physicochemical properties. The most promising molecules were synthesized and tested, and data on potency, selectivity, ADME and in vivo efficacy will be presented. Enki™ has enabled deep exploration of chemical space and rapid generation of de novo molecules, accelerating the drug discovery process and allowing discovery and development of CNS-penetrating dual ATR and mTOR inhibitors.", "source_company": "Vancouver Prostate Centre", "source_org_type": "研究机构", "row_number": 386, "target_meta": "mTOR,ATR", "MOA_meta": "抑制剂"}, {"drug_name": "IGF1R vaccine", "company": "Sequencio Therapeutics", "org_type": "公司", "target": "IGF1R", "modality": "vaccine", "importance_level": "中", "total_score": 51, "institution_score": 45, "track_score": 55, "milestone_score": 50, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "该疫苗针对IGF1R，通过诱导中和抗体阻断IGF1-IGF1R相互作用，在同系小鼠结肠癌模型中显示61-62%肿瘤生长抑制，为preclinical阶段概念验证。Sequencio为新兴子公司（母公司CK Life Sciences为国内上市公司），赛道为癌症疫苗虽有潜力但IGF1R非热门靶点且历史开发挑战多，导致综合评分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3641", "id": "hlXM_5wBX1NQZOEH-LG5", "source_drug_name": "IGF1R vaccine", "title": "Vaccine targeting IGF1R induces neutralizing antibody and robust anti-tumor activity in a syngeneic mouse colon cancer model", "abstract_text": "Background Insulin-like growth factors (IGFs) and their receptor (IGF1R) induce important cellular signalling that regulates cell proliferation, survival, and metabolism. Overexpression of IGF1R in cancers is associated with poor prognosis and resistance to conventional therapies, highlighting the need for innovative therapeutic strategy. In this study, we developed IGF1R vaccine candidates and evaluated their anti-tumor activity in a syngeneic mouse colon cancer model.\nMethods Recombinant proteins comprising different immune enhancers and computationally-predicted B-cell epitopes in the regions involved in IGF-IGF1R ligand-receptor interaction, intended to induce antibodies to block IGF-IGF1R interaction, were produced. Immunogenicity of the vaccine proteins was assessed in C57BL/6 mice by vaccination 6 times on days 0, 14, 28, 42, 49 and 56 using the proteins adjuvanted with CpG ODN 1826 and AS03. Serum samples were collected at multiple time points for determining anti-IGF1R antibody titers using ELISA as well as in vitro neutralization activity via blocking IGF1 binding to IGF1R using competitive ELISA. Anti-tumor efficacy of the vaccines was evaluated in a syngeneic MC38 mouse colon cancer model in C57BL/6 mice, which were vaccinated and inoculated subcutaneously with MC38 cells a week after the last vaccination. Mice administered adjuvant only were used as controls. Tumor growth was recorded twice a week till the end point.\nResults IGF1R vaccines induced robust humoral immune response as demonstrated by high titer of anti-IGF1R antibody. Importantly, serum samples collected from vaccinated mice demonstrated strong neutralizing activity, inhibiting IGF1 binding to IGF1R by up to 68% in a competitive ELISA. Two proteins which induced the highest antibody titer (i.e. 1:125,000) were further evaluated for their anti-tumor efficacy. In the anti-tumor study using the MC38 model, these two IGF1R vaccines suppressed the growth of tumors by 62% and 61%, respectively, at the study endpoint compared to controls (p<0.01).\nConclusions In summary, these findings establish proof-of-concept that IGF1R-targeting vaccines can elicit neutralizing antibodies that block IGF1 binding to IGF1R, thereby inhibiting the growth of tumors where IGF/IGF1R signalling plays critical roles. This result supports further investigation and optimization to improve these IGF1R vaccines to treat cancers dependent on IGF/IGF1R signalling.", "source_company": "Sequencio Therapeutics", "source_org_type": "公司", "row_number": 399, "target_meta": "IGF-1R", "MOA_meta": "疫苗"}, {"drug_name": "EGFR tyrosine kinase inhibitors", "company": "Kosin University", "org_type": "大学", "target": "EGFR", "modality": "inhibitor", "importance_level": "中", "total_score": 51, "institution_score": 30, "track_score": 80, "milestone_score": 60, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "药品为EGFR抑制剂，靶向罕见EGFR L833V/H835L顺式突变，该突变具有致癌性且对EGFR-TKI敏感，中位PFS达13个月。机构为大学，得分较低，但EGFR热门靶点+成熟TKI赛道+功能验证及临床证据使整体中等重要。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9870", "id": "flXM_5wBX1NQZOEH-LK6", "source_drug_name": "EGFR tyrosine kinase inhibitors", "title": "Rare EGFR cis compound L833V/H835L mutation in non-small cell lung cancer is oncogenic and a therapeutic target of EGFR tyrosine kinase inhibitors", "abstract_text": "Non-small cell lung cancer (NSCLC) with EGFR L833V/H835L in cis mutation remains poorly understood. We retrospectively reviewed the clinicopathologic features NSCLC with either EGFR L833V or H835L mutation. The study population includes NSCLC patients (n=3835) at Samsung Medical Center, Seoul, Korea. A total of 8 patients with EGFR L833V/H835L in cis mutation were identified. Poorly differentiated histology (either micropapillary or solid patterns) presented in 4 of 5 resected cases. Four patients received EGFR tyrosine kinase inhibitors (TKIs) and achieved a median progression-free survival of 13 months. The oncogenic and therapeutic properties of the mutation were investigated through a combination of functional and biochemical analyses, utilizing both in vitro and in vivo models, and structural modeling. The L833V/H835L mutant exhibited oncogenic potential, transforming NIH-3T3 cells and promoting IL3-independent growth in Ba/F3 cells. Furthermore, EGFR TKIs effectively suppressed the mutant's oncogenic activity in both in vitro and in vivo studies. These phenomena are further supported by its increased kinase activity in structural modeling. Although rare, EGFR L833V/H835L in cis mutation, represents a biologically oncogenic and clinically actionable variant in NSCLC.", "source_company": "Kosin University", "source_org_type": "大学", "row_number": 567, "target_meta": "EGFR", "MOA_meta": "抑制剂"}, {"drug_name": "CDK4/6 inhibitors", "company": "Syantra Inc", "org_type": "公司", "target": "CDK4/6", "modality": "inhibitor", "importance_level": "中", "total_score": 51, "institution_score": 45, "track_score": 75, "milestone_score": 35, "field_heat_score": 60, "bonus_score": 2, "brief_reason": "CDK4/6抑制剂通过逆转肿瘤诱导的单核细胞和血小板重编程，揭示其在乳腺癌中的新型免疫调节机制。Syantra作为初创biotech机构非头部，赛道为成熟靶点新机制有一定热度，但仍处preclinical机制研究阶段无新药开发里程碑。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10922", "id": "nVXM_5wBX1NQZOEH-LK6", "source_drug_name": "CDK4/6 inhibitors", "title": "New role for CDK6 activation in tumor-induced monocyte and platelet reprogramming in breast cancer", "abstract_text": "Background: Tumor-derived signals can reprogram immune cells and platelets to support cancer progression. However, the regulatory mechanisms underlying this systemic education are not well understood.\nMethods: RNA sequencing was performed on isolated platelet and white blood cell fractions from breast cancer patients and on THP-1 monocytes exposed to triple-negative breast cancer (TNBC) MDA-MB-231 cells. Transcriptomic data was analyzed using Ingenuity Pathway Analysis (IPA) and Gene Set Enrichment Analysis (GSEA) to identify upstream regulators and enriched pathways.\nResults: In both clinical and in-vitro datasets, CDK6 emerged as a key upstream regulator. In patient-derived platelets, CDK6 was identified as a major activated regulator in cancer versus non-cancer samples suggesting a role in tumor-driven systemic remodeling. The CDK6 regulatory network included upregulated and downregulated genes that were significantly modulated. In THP-1 monocytes following contact with TNBC cells, CDK6 activation was confirmed by IPA and accompanied by GSEA enrichment of cell cycle-related pathways such as “regulation of cell cycle process.” Functionally, THP-1 cells exposed to TNBC cells or conditioned media displayed increased proliferation, indicating tumor-induced monocyte reprogramming. This effect was reversed by CDK4/6 inhibitors, highlighting a new immunomodulatory mechanism of these standard-of-care drugs.\nConclusions and Translational Relevance: CDK4/6 activation represents a shared hallmark of tumor education across immune and platelet compartments. These findings reveal a novel mechanism of systemic immune modulation and suggest that CDK4/6 inhibitors can reverse oncogenic activation in monocytes and platelets. This study extends the relevance of these agents beyond tumor cell-intrinsic effects. Targeting CDK6-dependent immune reprogramming may offer a novel strategy to disrupt systemic tumor-immune crosstalk and improve therapeutic responses in breast cancer.", "source_company": "Syantra Inc", "source_org_type": "公司", "row_number": 585, "target_meta": "CDK4,CDK6", "MOA_meta": "抑制剂"}, {"drug_name": "STAT3 agents", "company": "ICE Bioscience", "org_type": "公司", "target": "STAT3", "modality": "other", "importance_level": "中", "total_score": 51, "institution_score": 45, "track_score": 75, "milestone_score": 35, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "针对STAT3转录因子，该靶点在多种肿瘤中异常激活但临床选择性抑制剂仍未实现，属于有潜力的但挑战大的经典靶点。ICE Bioscience作为国内CRO公司建立标准化评估平台比较多种化学类型STAT3 agents（包括PROTAC），处于preclinical工具/筛选阶段，无明确药物里程碑，综合热度中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3891", "id": "VFXM_5wBX1NQZOEH-LO6", "source_drug_name": "STAT3 agents", "title": "Side-by-side evaluation of STAT3 targeted agents in oncology", "abstract_text": "Signal transducer and activator of transcription 3 (STAT3) is a critical transcription factor, which is aberrant activated in hematological malignancies, including acute myeloid leukemia (AML) and chronic lymphocytic leukemia (CLL), as well as solid tumors of the lung, breast, and others. Yet no selective STAT3 inhibitor has reached the clinic owing to disparate chemical matter, binding sites (SH2, DBD, CCD), and mechanisms (pY705 blockade, dimer disruption, DNA binding inhibition, degradation). We established a standardized integrated analytics platform that directly compares 5-10 chemically diverse STAT3 agents—including covalent SH2 ligands, allosteric DBD antagonists and PROTAC degraders—using harmonized biochemical (FP, TR-FRET etc), biophysical (SPR, SPS etc), and cellular (pSTAT3, reporter gene, HiBiT, proliferation) assays. Family and species selectivity, together with resistance panels, reveal distinct vulnerability windows and mechanism-based liabilities for each modality. The same matrix is screened in combination with JAK, SRC, EGFR, and chemotherapy partners to quantify synergy landscapes; By providing a comprehensive molecular-evaluation platform, the program streamlines hit-to-lead decisions, propels STAT3-directed drug discovery and accelerates the path to the clinic.", "source_company": "ICE Bioscience", "source_org_type": "公司", "row_number": 710, "target_meta": "STAT3", "MOA_meta": "其他"}, {"drug_name": "SNAP (Selective Neoantigen Peptide)", "company": "Honor Health Research Institute", "org_type": "研究机构", "target": "HPV16 E6/E7/E2 + recurrent PIK3CA hotspot mutations", "modality": "therapeutic vaccine", "importance_level": "中", "total_score": 51, "institution_score": 35, "track_score": 75, "milestone_score": 45, "field_heat_score": 65, "bonus_score": 2, "brief_reason": "SNAP为个性化neoantigen peptide疫苗，结合OTS poly-epitope疫苗针对HPV16驱动癌；研究机构背景+preclinical阶段限制分数，但neoantigen+HPV off-the-shelf策略在精准免疫治疗赛道有一定热度。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1488", "id": "YJ7ECZ0BZznHJdntvNYd", "source_drug_name": "SNAP (Selective Neoantigen Peptide)", "title": "Accelerating precision immunotherapy for HPV-driven cancers", "abstract_text": "Background: HPV-related cancers affect nearly 48,000 Americans annually, with HPV16-driven cervical and oropharyngeal malignancies progressing rapidly and often outpacing current therapeutic timelines. Despite the success of prophylactic HPV vaccines in preventing infection in uninfected individuals, these agents provide no therapeutic benefit for patients with established invasive disease and fail to address the full spectrum of oncogenic HPV variants. To address this gap, we developed SNAP (Selective Neoantigen Peptide), a personalized therapeutic vaccine platform tailored to each patient’s tumor-specific neoantigen expression profile. SNAP has demonstrated potent immunogenicity and tumor control in preclinical models, validating its promise for precision immunotherapy. However, the extended manufacturing timeline-typically exceeding 12 weeks-for generating personalized SNAP vaccine severely limits applicability in rapidly progressing HPV16-positive tumors. To overcome this limitation, we have developed a dual-vaccination strategy that integrates an off-the-shelf (OTS) therapeutic vaccine for immediate immune priming with subsequent administration of the personalized SNAP vaccine. This study covers the development of the OTS HPV vaccine.\nMethods: The OTS vaccine is a poly-epitope construct targeting conserved HPV16 oncoproteins E6, E7, and E2, plus recurrent PIK3CA hotspot mutations (detected in >40% of HPV+ cancers), Candidate OTS peptides underwent comprehensive in silico predictive modeling. We used a multi-tiered computational pipeline to identify and prioritize immunogenic peptides for vaccine development, anchored by ProtIQ, a modular antigen selection tool. Top 100 peptides were ranked by immunogenicity, coverage and stability. A subset was synthesized and validated via biolayer interferometry (BLI) for binding kinetics. Human IFN-γ ELISPOT on HLA-matched donor PBMCs assessed T-cell activation to select final candidates.\nResults: In silico prediction of OTS peptides yielded high-confidence epitopes with high median immunogenicity scores, across prevalent HLA class I and II alleles. BLI confirmed stable peptide-MHC complexes (KD range 102-103 nanomoles) in a validated subset. ELISPOT on individual peptide pulsed HLA-matched healthy donor PBMCs demonstrated robust IFN-γ responses. Top 30 peptides with highest ELISPOT signals were selected as vaccine candidates. To check the vaccine efficacy in vivo, mouse TC-1 cells engineered to express E2 and PIK3ca mutations will be used as HPV preclinical animal model.\nConclusions: This project will deliver a clinically actionable off-the-shelf vaccine platform that enables early immunologic intervention in HPV16-driven cancers. By priming the immune system ahead of personalized therapy, we aim to reduce time-to-treatment, enhance therapeutic outcomes, and expand access to precision immunotherapy.", "source_company": "Honor Health Research Institute", "source_org_type": "研究机构", "row_number": 734, "target_meta": "PI3Kα,HPV E7,HPV E6,HPV E2", "MOA_meta": "疫苗"}, {"drug_name": "redirected cytomegalovirus immunity", "company": "La Jolla Institute for Immunology and Allergy", "org_type": "研究机构", "target": "未披露", "modality": "other", "importance_level": "中", "total_score": 51, "institution_score": 40, "track_score": 75, "milestone_score": 40, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "利用CMV病毒特异性T细胞通过肽递送重定向至乳腺肿瘤的新免疫治疗策略，靶点和具体机制未明确披露。研究机构背景导致机构分较低，但病毒重定向免疫机制创新且针对难治实体瘤有潜力，赛道热度较高，目前处于preclinical探索阶段。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11537", "id": "cZ7ECZ0BZznHJdntvNYd", "source_drug_name": "redirected cytomegalovirus immunity", "title": "Redirecting cytomegalovirus immunity against breast tumors for immunotherapy", "abstract_text": "Abstract is embargoed at this time.", "source_company": "La Jolla Institute for Immunology and Allergy", "source_org_type": "研究机构", "row_number": 886, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "anti-PD-1", "company": "University of Pennsylvania", "org_type": "大学", "target": "PD-1", "modality": "inhibitor", "importance_level": "中", "total_score": 51, "institution_score": 35, "track_score": 85, "milestone_score": 40, "field_heat_score": 80, "bonus_score": 0, "brief_reason": "anti-PD-1为经典免疫检查点抑制剂，靶向PD-1的赛道热度高且临床验证充分，但研究来自大学机构且为机制性基础研究而非药物开发里程碑。总分中等主要因机构类型非商业头部公司且无新药开发推进。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5259", "id": "WZ7M_5wBZznHJdnt_W3O", "source_drug_name": "anti-PD-1", "title": "Anti-PD-1 efficacy is associated with a clonal trajectory composed of chronic effectors with lymph node homing capacity", "abstract_text": "Introduction: Immune checkpoint blockade (ICB), such as anti-CTLA-4 or anti-PD-1 (αPD-1), drives distinct patterns of T cell differentiation that ultimately influence treatment efficacy. However, it has been challenging to identify and define distinct T cell differentiation states in humans. We apply a novel algorithm Clonotrace (Nancy Zhang, UPenn) to define differentiation trajectories by monitoring single clones across differentiation states after αPD-1. We test the hypothesis that certain differentiation trajectories will have unique properties, including cell states and trafficking patterns, that will influence clinical efficacy.\nMethods: We performed single cell RNA and paired TCR sequencing on 132,898 CD8+ T cells from 36 stage III melanoma patients treated with neoadjuvant αPD-1, including 12 patients with matched tumor, uninvolved regional lymph node, and blood samples. We applied Clonotrace to define differentiation trajectories by grouping clonotypes that have a similar transcriptional footprint across CD8 cell states. We then defined these differentiation trajectories in terms of cell state composition, antigen specificity, tissue distribution, gene regulation, and association with clinical outcomes.\nResults: We identified 10 distinct clonal trajectories that differentiate from naïve/stem-like CD8 T cell states to exhausted and/or effector CD8 T cell states. These trajectories largely separated into two sets of clones based on antigen specificity and the expression of pathways associated with chronic stimulation. Further examination of the antigen-specific clones identified one particular trajectory (Traj 5), that was associated with clinical response. Traj 5 included clones with a unique chronic effector cell state that was able to traffic between lymph node and tumor. In contrast, Traj 1 was composed of terminally exhausted CD8 clones that were tumor-resident and associated with αPD-1 resistance.\nConclusion: We identify a unique differentiation trajectory in patients that retains effector T cell differentiation in the setting of chronic stimulation. These chronic effectors retain the ability to traffic between lymph node and tumor and are associated with the efficacy of αPD-1. These findings indicate maintaining trafficking ability is essential for the efficacy of ICB. In contrast, terminal differentiation results in CD8 T cells becoming “locked” in the tissue and terminally exhausted.", "source_company": "University of Pennsylvania", "source_org_type": "大学", "row_number": 1011, "target_meta": "PD1", "MOA_meta": "抑制剂"}, {"drug_name": "immune checkpoint blockade", "company": "Johns Hopkins University", "org_type": "大学", "target": "未披露", "modality": "inhibitor", "importance_level": "中", "total_score": 51, "institution_score": 35, "track_score": 75, "milestone_score": 40, "field_heat_score": 80, "bonus_score": 0, "brief_reason": "该记录研究肠道代谢物TMAO与免疫检查点阻断疗法（ICB）在新辅助治疗中的相关性，而非新药开发，靶点未明确披露具体分子。机构为大学得分较低，但ICB赛道及免疫治疗领域整体热度较高，临床相关性观察具有一定价值。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9195", "id": "pp3ECZ0B4z9FlvORyiZD", "source_drug_name": "immune checkpoint blockade", "title": "Elevated plasma trimethylamine-N-oxide (TMAO) levels correlate with better clinical and molecular responses in immunotherapy-treated resectable gastroesophageal cancer and pleural mesothelioma", "abstract_text": "Background: Microbiome-derived metabolites have demonstrated significant impact on immunotherapy response, particularly in the context of immune checkpoint blockade (ICB). Trimethylamine-N-oxide (TMAO), an amine oxide generated when gut bacteria metabolize dietary choline, has been identified in preclinical studies to enhance anti-tumor immune responses. Here, we evaluated circulating choline metabolites with respect to clinical outcomes and circulating tumor DNA (ctDNA) residual disease in patients with resectable cancers receiving neoadjuvant ICB.\nMethods: Pre-treatment choline, trimethylamine (TMA) and TMAO plasma concentrations from 51 patients with stage I-III diffuse pleural mesothelioma (DPM; n = 25 patients; NCT03918252) or stage II/III esophageal/gastro-esophageal junction cancer (E/GEJ; n = 26 patients; NCT03044613) on neoadjuvant ICB, were quantified via liquid chromatography-mass spectrometry (SCIEX Triple Quad 6500+). Clinical outcomes were compared across metabolite thresholds, as were ctDNA residual disease through tumor-informed cell-free DNA (cfDNA) whole-genome sequencing (WGS). ctDNA residual disease in the DPM cohort was measured by intersecting tumor (n = 28), white blood cell (n = 28), and plasma (n = 97) WGS.\nResults: In the DPM cohort, median baseline choline, TMA and TMAO concentrations were 3970, 2840 and 256 ng/mL, respectively. Higher baseline TMAO levels were associated with lower ctDNA residual disease at C2D1 (Fisher’s exact, p = 0.028), C3D1 (Fisher’s exact, p = 0.057) and pre-surgery (Fisher’s exact, p = 0.01). Further, patients with higher TMAO had either undetectable ctDNA throughout the neoadjuvant window or ≥95% reduction in cfDNA tumor fraction from baseline to pre-surgery (Fisher’s exact, p = 0.028). In this cohort, ctDNA residual disease strongly correlated with progression-free and overall survival (log-rank, p < 0.05). In the E/GEJ cohort, median baseline choline, TMA and TMAO concentrations were 279, 2945 and 4175 ng/mL, respectively. Patients who attained a major pathologic response had numerically higher TMAO levels (Fisher’s exact, p = 0.078). In line with the findings in the DPM cohort, patients in the E/GEJ cohort with lower TMAO (lowest quintile; <197 ng/mL) had shorter overall survival (log-rank, p = 0.034) compared to those with higher TMAO concentration ( ≥197 ng/mL), an association that remained significant after adjusting for clinicopathological variables (Cox multivariable, p = 0.04).\nConclusion: Our findings indicate that higher plasma TMAO levels may be linked to molecular ctDNA response and better clinical outcomes with neoadjuvant ICB, further supporting a potential immunomodulatory role of choline metabolites in enhancing immunotherapy response.", "source_company": "Johns Hopkins University", "source_org_type": "大学", "row_number": 1058, "target_meta": "not available", "MOA_meta": "抑制剂"}, {"drug_name": "ARNTi", "company": "Cedars-Sinai Medical Center", "org_type": "医院", "target": "ARNT", "modality": "inhibitor", "importance_level": "中", "total_score": 51, "institution_score": 35, "track_score": 75, "milestone_score": 45, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "ARNTi为ARNT选择性小分子抑制剂，通过阻断HIF-1α和HIF-2α与ARNT的二聚化抑制肾癌细胞HIF信号和增殖。机构为医院学术型，得分较低；赛道涉及HIF通路在ccRCC中重要性较高，但仅preclinical原代细胞数据，里程碑价值有限，总分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8889", "id": "7p7M_5wBZznHJdnt_W3O", "source_drug_name": "ARNTi", "title": "Inhibition of ARNT suppresses growth of primary human kidney cancer cells", "abstract_text": "Background: Hypoxia‑inducible factor (HIF) signaling drives clear cell renal cell carcinoma (ccRCC). ARNT (HIF‑1β) dimerizes with HIF‑1α and HIF‑2α to enable gene transcription. Belzutifan is a small-molecule drug that blocks HIF-2α, which is approved for clinical use. It’s been proposed that increased signaling through HIF-1α represents a belzutifan-resistance mechanism. Blocking ARNT should attenuate both HIF programs. We assessed an ARNT‑selective small‑molecule inhibitor (ARNTi) in renal cancer models.\nMethods: 786‑O cells were cultured under hypoxia. Cells received belzutifan, ARNTi, or vehicle control (DMSO). After treatment, cells were fixed, and the interaction between HIF‑2α and ARNT was quantified using a proximity ligation assay. Primary cultures were generated from patients who underwent nephrectomy. Under hypoxia, both normal and ccRCC primary cell cultures were exposed to ARNTi or vehicle and then processed for proliferation assessment and qPCR of HIF target genes. Primary papillary renal cell carcinoma cultures were evaluated using the same workflow.\nResults: ARNTi lowered the proximity ligation signal between HIF‑2α and ARNT. The extent of inhibition matched the effect of belzutifan. In patient‑derived ccRCC cultures (n=5), ARNTi produced significant growth inhibition under hypoxia compared with vehicle. The magnitude of the effect was similar to belzutifan. Expression of hypoxia‑responsive target genes, such as GLUT1, NDRG1, and VEGFa, decreased after ARNTi treatment. ARNTi also suppressed growth in papillary renal cell carcinoma cultures (n=3), indicating activity across histologic subtypes.\nConclusions: Inhibition of ARNT reduces the formation of the HIF‑2α and ARNT complex and suppresses proliferation in primary human kidney cancer cells. These effects coincide with reduced expression of HIF target genes under hypoxia. These results support the development of ARNT‑directed candidates for the treatment of kidney cancer.", "source_company": "Cedars-Sinai Medical Center", "source_org_type": "医院", "row_number": 1117, "target_meta": "ARNT", "MOA_meta": "抑制剂"}, {"drug_name": "CPA-7", "company": "University of Southern California", "org_type": "大学", "target": "STAT3", "modality": "inhibitor", "importance_level": "中", "total_score": 51, "institution_score": 30, "track_score": 70, "milestone_score": 70, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "CPA-7为小分子STAT3抑制剂（铂类化合物），通过阻断STAT3二聚体DNA结合诱导HPV+肿瘤细胞死亡并增强T细胞抗肿瘤活性。大学机构基础研究背景得分较低，但STAT3作为经典靶点在肿瘤免疫领域有较高热度，且in vivo显示晚期肿瘤完全清除及免疫记忆的强preclinical数据，支持中等重要性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1475", "id": "8Z7M_5wBZznHJdnt_W3O", "source_drug_name": "CPA-7", "title": "Targeting STAT3 promotes cell death and enhances T-cell activity in HPV-associated cancer", "abstract_text": "Human papillomavirus oncoproteins early (E)6 and E7 are crucial for sustaining chronic infection and driving malignant transformation in stratified epithelia when the immune system fails to clear the virus. In addition to impairing the cellular surveillance systems that maintain genomic integrity and promoting cell cycle progression, these oncoproteins increase interleukin-23 (IL-23) production by tumor-associated macrophages in HPV⁺ cancers, leading to suppression of local tumor-specific T-cell immunity. IL-23 signaling through the IL-23 receptor (IL-23R) on HPV-specific CD8⁺ T cells reduces their cytotoxicity and proliferative capacity. Downstream, IL-23R activates signal transducer and activator of transcription 3 (STAT3), a transcription factor known to drive multiple cancer hallmarks.\nTo investigate how STAT3 signaling affects both the progression of HPV+ tumors and specifically the T-cell response against its E6 and E7 proteins, we employed the C3.43 syngeneic murine tumor model, which expresses the full length HPV16 genome under its native promoters, and used the cisplatin derived small molecule inhibitor CPA-7 to inhibit STAT3. IL-23R signaling induces phosphorylation of STAT3 monomers (pSTAT3), leading to their dimerization and subsequent nuclear translocation, where they bind DNA. CPA-7 prevents dimerized STAT3 from binding DNA and functionally reduces overall pSTAT3 levels. In vitro treatment of HPV⁺ C3.43 tumor cells with CPA-7 revealed that STAT3 inhibition induces tumor cell death. In vivo, mice challenged with C3.43 tumor cells and treated with CPA-7 completely eradicated their tumors, with 4 of 10 mice demonstrating durable immune memory upon tumor re-challenge. Remarkably, even established, late-stage HPV⁺ tumors were fully eradicated upon CPA-7 treatment. Full eradication required an intact adaptive immune system, as CPA-7 treatment failed to eliminate HPV⁺ tumors in mice lacking both CD4⁺ and CD8⁺ T cells. Together, these data demonstrate that STAT3 promotes HPV⁺ tumor cell survival and suppresses the adaptive, tumor-specific T-cell immune response. Targeting STAT3 may therefore represent a promising strategy to induce tumor cell death and counteract IL-23-induced, STAT3-mediated immune suppression in HPV-associated cancers.", "source_company": "University of Southern California", "source_org_type": "大学", "row_number": 1118, "target_meta": "STAT3", "MOA_meta": "抑制剂"}, {"drug_name": "anti-PD-1", "company": "Zhongshan Hospital Fudan University", "org_type": "医院", "target": "PD-1", "modality": "inhibitor", "importance_level": "中", "total_score": 50.8, "institution_score": 25, "track_score": 75, "milestone_score": 60, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "anti-PD-1为经典免疫检查点抑制剂，靶向PD-1，但本研究中仅作为联合用药工具，未披露新型anti-PD-1药物；机构为国内顶尖医院，赛道为热门的肿瘤微环境+免疫治疗组合，preclinical模型显示联合阻断EP3可显著增敏anti-PD-1。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/7444", "id": "OlXM_5wBX1NQZOEH-LK6", "source_drug_name": "anti-PD-1", "title": "Targeting EP3⁺FAP⁺ stromal reprogramming uncovers a therapeutic vulnerability in early recurrent hepatocellular carcinoma", "abstract_text": "Early recurrence after curative therapy remains a major obstacle in hepatocellular carcinoma (HCC), yet the stromal determinants of early relapse are poorly defined. Across integrated mouse and human datasets, this stromal program was consistently associated with early relapse. Integrating bulk, single-cell and spatial transcriptomics with functional assays from primary and relapse HCC, we identify a recurrence-enriched cancer-associated fibroblast (CAF) population marked by FAP and EP3. A CAF- and neutrophil-derived high-risk gene signature predicted early relapse and was accompanied by expansion of FAP⁺EP3⁺ CAFs, immunosuppressive neutrophils and stem-like tumor epithelial cells in relapsed lesions. Lineage and perturbation studies indicate that CD36⁺ lipid-associated CAFs are reprogrammed by tumor-derived PGE₂ into FAP⁺EP3⁺ matrix CAFs, linking stromal plasticity to recurrence. Mechanistically, FAP physically associates with EP3 on CAFs to potentiate PGE₂-induced EP3 signaling, thereby amplifying downstream cAMP-PKA activation. This FAP-EP3 complex drives a proline-metabolic, senescent and inflammatory CAF phenotype characterized by PYCR1-dependent proline production and SASP factors including IL-6 and TIMP1. PGE₂-FAP-EP3-cAMP/PKA signaling engages the chromatin reader BRD9 and pioneer factor FOXA1 to establish super-enhancer landscapes at IL6, FAP, PYCR1 and TIMP1, locking EP3⁺FAP⁺CAFs into a relapse-permissive state and sustaining SASP output. Imaging mass cytometry and spatial analyses revealed that EP3⁺FAP⁺ CAFs organize relapse-associated niches enriched for neutrophils, CD44⁺/CD133⁺ stem-like tumor cells, FOXP3⁺ Tregs and CD163⁺ macrophages, in close apposition to invasive tumor fronts. In autochthonous HCC models, genetic deletion of EP3 in fibroblasts or pharmacologic blockade of EP3 or BRD9 reduced tumor burden, decreased pro-tumoral neutrophils and exhausted CD8⁺ T cells, and enhanced effector CD8⁺ differentiation. Combined EP3 inhibition and anti-PD-1 therapy produced superior tumor control, indicating that stromal targeting can sensitize HCC to immune checkpoint blockade. In human HCC cohorts, EP3⁺FAP⁺ CAF signatures correlated with T cell exhaustion, high PTGES expression and poor survival, validating the clinical relevance of this stromal program. Together, our data uncover a PGE₂-FAP-EP3-cAMP/PKA-BRD9-FOXA1 axis that epigenetically locks CAFs into a relapse-permissive, metabolically active SASP state and remodels the immune microenvironment. Targeting EP3⁺FAP⁺ CAFs or their epigenetic circuitry represents a promising strategy to limit HCC recurrence and improve responsiveness to immunotherapy.", "source_company": "Zhongshan Hospital Fudan University", "source_org_type": "医院", "row_number": 522, "target_meta": "PD1", "MOA_meta": "抑制剂"}, {"drug_name": "Zα-targeting ADAR1 inhibitor", "company": "Cancer Research Malaysia", "org_type": "研究机构", "target": "ADAR1 p150 Zα domain", "modality": "inhibitor", "importance_level": "中", "total_score": 50.8, "institution_score": 35, "track_score": 75, "milestone_score": 45, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "靶向ADAR1 p150特异性Zα结构域的小分子抑制剂，针对亚洲OSCC患者未满足需求，具有新型RNA编辑调控机制。机构为研究机构得分较低，但靶点新颖且赛道潜力较高，目前处于早期体外验证阶段，整体重要性中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6516", "id": "elXM_5wBX1NQZOEH-LO6", "source_drug_name": "Zα-targeting ADAR1 inhibitor", "title": "Targeting the interferon-inducible isoform, p150 of ADAR1 for the treatment of oral squamous cell carcinoma (OSCC)", "abstract_text": "Oral squamous cell carcinoma (OSCC) is the fourth most common cancer in low- and middle-income countries (LMIC) and is one of the leading causes of cancer deaths in Asia, accounting for nearly three-quarters of global oral cancer mortality. Five-year survival rates remain poor, reflecting both the scarcity of actionable genetic drivers and the absence of Asian patient-derived models in global cancer datasets. This underrepresentation has slowed therapeutic innovation for populations that bear the greatest burden, leaving a significant unmet clinical need. To address this gap, we conducted genome-wide CRISPR/Cas9 dependency screens on a panel of unique Asian-derived OSCC cell lines that reflect the genetic and etiological diversity of these patients to identify vulnerabilities for therapeutic development. We have identified Adenosine deaminase acting on RNA (ADAR1) as an essential gene for OSCC survival. ADAR1 is an RNA-editing enzyme, whereby its dysregulation has been associated with tumor progression in various cancers. There are two isoforms of ADAR1 (p110 and p150), which are identical except that p150 has a unique Zα domain, which binds Z-DNA and offers a unique targeting opportunity to treat this deadly OSCC. To take this forward, we applied a proprietary computer-aided drug discovery pipeline, termed the Multi-layer Ultra-large Screening and Exploration (M.U.S.E), to identify potential Zα-targeting ADAR1 inhibitors. Approximately six billion compounds were evaluated through integrated filters for solubility, drug-likeness, binding affinity, and stability. A total of 51 compounds were shortlisted from the in-silico screening, and their binding affinities and specificities were evaluated. The intrinsic tryptophan fluorescence (ITF) spectroscopy was used to determine the binding affinity, while the electrophoretic mobility shift assay (EMSA) was used to determine the on-target effect of the compounds in disrupting the Zα-Z-DNA binding. From ITF analysis, 21 compounds demonstrated strong binding affinity with Stern-Volmer constants (KSV) exceeding 10,000 M-1. Using EMSA, we identified eight compounds with robust evidence of disruption of Zα-Z-DNA binding complexes. Our selected top hits demonstrated better binding affinity and on-target efficacy in disrupting ADAR1-Zα function, compared to other reported experimental candidates of ADAR1 inhibitors. While further effort in the hit-to-lead optimization and validation of its anti-tumor efficacy in OSCC cells are still ongoing, the discovery of these top hits with validated binding affinity and functional efficacy assures a promising outlook of our drug discovery strategy.", "source_company": "Cancer Research Malaysia", "source_org_type": "研究机构", "row_number": 731, "target_meta": "ADAR", "MOA_meta": "抑制剂"}, {"drug_name": "PARP inhibitor", "company": "University of Cambridge", "org_type": "university research institution", "target": "PARP", "modality": "inhibitor", "importance_level": "中", "total_score": 50.5, "institution_score": 35, "track_score": 75, "milestone_score": 45, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "PARP抑制剂靶向PARP酶，主要用于HRD相关卵巢癌的维持治疗，但摘要聚焦于新型WGS生物标志物分型而非药物本身新进展。机构为大学研究机构非产业化主体、未展示具体药物里程碑导致总分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9759", "id": "WFXM_5wBX1NQZOEH-LS6", "source_drug_name": "PARP inhibitor", "title": "DNA repair phenotypes inform carboplatin and PARP inhibitor response", "abstract_text": "High-grade ovarian carcinoma (HGOC) is characterized by multilayered genomic complexity driven by early disruption of the p53 pathway which enables diverse mutational processes and chromosomal instability (CIN). The molecular consequences of defective DNA repair and replication have been used to derive mutational signatures to predict mutational processes operative in each HGOC. Clinical testing for homologous recombination deficiency (HRD) signatures does not reliably guide the use of platinum-based therapy or poly(ADP-ribose) polymerase inhibitors (PARPi) for women with HGOC. Previous studies have shown that multiple HRD signatures are operative at the single-base substitution, indel, and structural variant levels in the same tumors. However, separate signatures do not capture the continuum of erroneous repair programs active in BRCA1- and BRCA2-deficient tumors. Here, we propose a new integrative mathematical approach to recover all naturally occurring genomic features associated with operational DNA repair pathways. We established a national healthcare outcome study of 466 HGOC patients, integrating tumor-normal deep whole-genome sequencing (WGS) with real-world treatment and outcomes. We demonstrated that seven integrative genomic features (IGFs) capture the mutational programs operative in HGOC tumors. We validated the clinical relevance of these IGFs using causal-inference methods. IGF2 captured microhomology‑flanked deletions, templated insertions (TINs), and interstitial deletions. IGF5 captured 1 kilobase (kb) to multi‑megabase (Mb) tandem duplications (TDs) and blunt deletions. IGF8 was rich in inversions and multi‑Mb TDs, whereas IGF10 linked CpG transversions with TINs. IGF2 reflects polymerase theta-mediated end joining, associated with BRCA2 inactivation, favorable prognosis after first-line platinum, and reduced benefit from maintenance PARP inhibitors. IGF5, marked by tandem duplications and non-homologous end joining, is enriched in BRCA1-inactivated tumors and predicts earlier relapse but increased benefit from maintenance PARPi. In Cox models (per 1 standard deviation unit), IGF2 improved overall survival (OS) (HR 0.81, 95% CI 0.71-0.92) and IGF8 was adverse (HR 1.25, 1.08-1.46), and IGF10 predicted benefit at second‑line relapse when half of patients received maintenance PARPi (progression-free survival HR 0.75, 0.62-0.89). IGF2 modified second-line PARPi benefit ( IGF2-binary x PAPRi interaction P=0.042), with benefit confined to IGF2‑low. This WGS-based taxonomy reframes HRD as a continuum of DNA double-strand break repair choices. The mechanism-specific, WGS-derived phenotypes can be replicated in clinical practice, providing a basis for biomarker-stratified trials of PARP inhibitors and emerging polymerase theta (POLQ) inhibitors in ovarian cancer and in other tumors with DNA-repair defects.", "source_company": "University of Cambridge\nCRUK Cambridge Institute, University of Cambridge", "source_org_type": "大学\n研究机构", "row_number": 75, "target_meta": "PARP", "MOA_meta": "抑制剂"}, {"drug_name": "FGFR inhibitor", "company": "University of Colorado", "org_type": "大学", "target": "FGFR1", "modality": "inhibitor", "importance_level": "中", "total_score": 50.5, "institution_score": 35, "track_score": 75, "milestone_score": 45, "field_heat_score": 65, "bonus_score": 0, "brief_reason": "FGFR1作为ER+乳腺癌脑转移的关键驱动因子，通过canonical和non-canonical机制（包括NCAM1介导的神经元/星形胶质细胞激活）促进早期定植，FDA批准FGFR抑制剂在年轻小鼠早期阶段显示预防脑转移潜力。大学机构得分较低，但FGFR靶点在乳腺癌内分泌耐药及脑转移领域有一定热度，整体处于机制探索阶段而非明确药物开发里程碑。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10715", "id": "Fp7M_5wBZznHJdnt_W7O", "source_drug_name": "FGFR inhibitor", "title": "FGFR1 drives progression of ER+ breast cancer brain metastases in young and aged hosts", "abstract_text": "The purpose of these studies is to define mechanisms that drive estrogen receptor positive (ER+) breast cancer brain metastasis (BCBM) colonization and outgrowth. Most ER+ BCBMs arise in postmenopausal women due to prior endocrine therapies or age, yet most in vivo ER+ breast cancer (BC) models require estrogen (E2) supplementation and use young hosts. Thus, the mechanisms underlying metastatic progression in the aged/E2-depleted brain tumor microenvironment (TME) remain unknown. FGFR1-amplification (amp), an established driver of ER+ BC endocrine therapy resistance, was the only genomic alteration associated with increased late recurrence in post-menopausal women with ER+ BC on aromatase inhibitors, and FGFR aberrations are enriched in BCBM patients compared to non-BM metastatic BC. While FGFR1amp often causes auto-activation, TME-dependent FGFR1 activation has emerged as an important mechanism modulating its activity. Here, we tested the hypothesis that canonical and non-canonical activation of FGFR1 by astrocytes and neurons promotes FGFR1-dependent ER+ BCBM in E2-high young and E2-low aged hosts. Intracardiac injection of ER+ cells showed that FGFR1amp lines had higher BM incidence, and were E2-dependent in young but not aged hosts. FGFR1 knockdown (KD) did not alter proliferation but decreased BCBM in both E2-high/young and E2-low/aged mice. Spatial transcriptomics of the ER+ BCBMs TME showed that aging and E2-depletion reduced FGF2 expression and FGF/FGFR signaling in surrounding glial cells, suggesting that TME-driven FGFR1 activation may be distinct in young and aged hosts. In the normal brain, NCAM1, an adhesion molecule expressed on neurons and astrocytes, can activate FGFR1. We found that NCAM1 activated FGFR1 kinase activity and downstream signaling in ER+ BC cells, and induced differential expression of neuronal gene signatures including neural cell adhesion. FGFR1 KD reduced ER+ BC cell migration along neurites in co-culture with primary neurons and decreased synaptic puncta. NCAM1 KD in neuron-like SH-SY5Y cells also decreased ER+ cell migration, suggesting that FGFR1/NCAM1 facilitates ER+ BC interactions with neurons, contributing to early brain colonization. Activated FGFR1 was higher in young versus aged mice at early stages of colonization but absent in late-stage ER+ BCBMs, suggesting that paracrine FGFR1 activation and interactions with neurons and astrocytes are critical for early colonization. Consistently, an FDA-approved FGFR inhibitor blocked ER+ BCBM when administered at early stages of colonization in young mice but had no effect at late stages or in aged mice. Together, these studies suggest a novel mechanism whereby canonical and non-canonical activation of FGFR1 promote ER+ BCBM colonization in young and aged/E2-depleted hosts, and caution that FGFR1 inhibition may only be effective to prevent but not to treat BMs.", "source_company": "University of Colorado", "source_org_type": "大学", "row_number": 95, "target_meta": "FGFR1", "MOA_meta": "抑制剂"}, {"drug_name": "TKG-002", "company": "University of Tokyo", "org_type": "大学", "target": "miR-21", "modality": "other", "importance_level": "中", "total_score": 50.5, "institution_score": 35, "track_score": 75, "milestone_score": 45, "field_heat_score": 65, "bonus_score": 3, "brief_reason": "TKG-002通过与肿瘤高表达的miR-21结合自组装成长双链DNA，激活cGAS-STING通路实现选择性肿瘤免疫杀伤。大学机构得分较低，但核酸药物+肿瘤选择性+新型cGAS-STING激活机制具有一定创新性和赛道热度，动物模型显示较强抑瘤效果。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6481", "id": "u1XM_5wBX1NQZOEH-LG6", "source_drug_name": "TKG-002", "title": "Selective tumor immune activation by novel nucleic acid drug", "abstract_text": "Introduction: Cancer-selective immune activation by artificial nucleic acids holds promise as a potent therapeutic modality for cancer treatment. We developed a hairpin DNA self-assembly technology and found it effectively suppresses tumor growth. Specifically, our developed compound TKG-002 activated cellular innate immunity and demonstrated potent tumor growth inhibition. Here, we discuss the results of tumor growth suppression by TKG-002.\nExperimental Design: Two hairpin DNA sequences (oHP) were designed. Among these, the oHP showing the strongest cancer growth suppression effect in B16 tumor-bearing mice was selected and named TKG-002. In vitro tests confirmed TKG-002's self-assembly triggered by binding to miR-21. We also investigated the induction of innate immune activation that causes cancer growth suppression.\nResults: TKG-002 was confirmed to aggregate under conditions of abundant miR-21 expression, forming long double-stranded DNA to which cGAS binds. Administration of TKG-002 to cancer cells induced apoptosis via the cGAS-STING pathway, including the production of phosphorylated IRF3. When TKG-002 was administered intra-tumorally to B16-bearing mice using an appropriate DDS, tumor growth was strongly suppressed. Aggregates of CD8+ T cells and CD4+ T cells were observed at the periphery of the shrinking tumor tissue. While TKG-002 alone demonstrated sufficient tumor growth suppression, combination with anti-PD-1 antibody resulted in even greater tumor growth inhibition.\nConclusions: The suppression of miR-21-overexpressing cancer growth by TKG-002 represents a potent therapeutic modality enabling selective tumor lysis through intracellular DNA self-assembly. The engineered TKG-002 induced autoimmunity toward targeted tumor lysis by forming long double-stranded DNA via miR-21. Further safety evaluation and condition optimization of TKG-002 are expected to establish it as an efficient cancer treatment modality.", "source_company": "University of Tokyo", "source_org_type": "大学", "row_number": 197, "target_meta": "miR-21", "MOA_meta": "其他"}, {"drug_name": "PKM activators", "company": "NYU Langone Health", "org_type": "医院", "target": "pyruvate kinase (PKM)", "modality": "other", "importance_level": "中", "total_score": 50.5, "institution_score": 35, "track_score": 65, "milestone_score": 55, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "靶向PKM激活剂选择性杀伤BRCA1/2缺陷肿瘤细胞，通过诱导DNA损伤和线粒体功能障碍，机制新颖但非热门靶点。机构为医院/学术型，得分受限；赛道为肿瘤代谢新策略，preclinical阶段有较强机制验证和选择性数据，综合热度中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8988", "id": "BlXM_5wBX1NQZOEH-LG5", "source_drug_name": "PKM activators", "title": "Targeting metabolism in BRCA-deficient tumors", "abstract_text": "Up to 10% of all cancers are attributed to genetic predisposition, with inherited mutations in BRCA1 and BRCA2 being the most significant risk factors for developing breast and ovarian cancers. These mutations also increase susceptibility to other malignancies, including prostate, pancreatic, and colorectal cancers. The BRCA1 and BRCA2 proteins play essential roles in homologous recombination (HR), an error-free DNA repair process. When cells lack functional BRCA1 or BRCA2, they become reliant on alternative, error-prone DNA repair mechanisms, which drive genomic instability and tumorigenesis. Although Poly (ADP-ribose) polymerase (PARP) inhibitors have revolutionized targeted therapy for tumors with BRCA1/2 mutations, the emergence of resistance limits their long-term efficacy, highlighting the urgent need for novel therapeutic strategies. Cancer metabolism of BRCA1/2-deficient tumors remains largely uncharacterized and poorly understood.To address this gap, we analyzed 10,619 tumors representing 33 cancer types using data from The Cancer Genome Atlas (TCGA). Our findings revealed that tumors with HR deficiency signatures exhibit distinct metabolic profiles compared to HR-proficient tumors. Further validation in BRCA2-/- cancer cell models confirmed that BRCA2-deficient tumor cells rely heavily on the activity of pyruvate kinase (PK), an enzyme that catalyzes the final step of glycolysis. Pyruvate kinase exists as two splice isoforms: PKM1, which is constitutively active, and PKM2, which is allosterically regulated. Most cancer cells predominantly express PKM2, as its low activity state enables metabolic flexibility by redirecting glucose-derived carbons from energy production to biosynthesis for growth and survival. Remarkably, we showed for the first time that BRCA1/2-deficient tumor cells and mouse-derived tumors, not only express PKM2, but also the constitutively active PKM1. Therefore, we targeted PKM, and we found that PKM activators selectively kill BRCA2-deficient cancer cells, but not BRCA2-proficient ones, by inducing DNA damage, reducing lactate production, and decreasing glucose oxidation. Notably, PKM1 overexpression in BRCA2-proficient cells phenocopies the sensitivity of BRCA2-deficient cells to PKM activators, suggesting that PKM1 mediates, at least in part, this effect. Our results also reveal that the toxic impact of PKM activators in BRCA2-deficient cancer cells involves impaired mitophagy and mitochondrial dysfunction.\nTogether, these findings provide a strong rationale for targeting pyruvate kinase in BRCA1/2 deficient and potentially other HR-deficient tumor subtypes.", "source_company": "NYU Langone Health", "source_org_type": "医院", "row_number": 316, "target_meta": "PKM", "MOA_meta": "其他"}, {"drug_name": "an orally bioavailable AR-NTD degrader", "company": "Chang Gung University", "org_type": "大学", "target": "AR-NTD", "modality": "PROTAC", "importance_level": "中", "total_score": 50.5, "institution_score": 25, "track_score": 85, "milestone_score": 40, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "药物为靶向AR-NTD的口服PROTAC降解剂，可绕过LBD依赖性耐药并抑制AR-V7介导的反馈，主要用于晚期前列腺癌；大学机构研发分数较低，但PROTAC+AR-NTD在CRPC耐药领域具有较高赛道热度和临床潜力。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11699", "id": "bVXM_5wBX1NQZOEH-LG5", "source_drug_name": "an orally bioavailable AR-NTD degrader", "title": "An orally bioavailable AR-NTD degrader that bypasses LBD-dependent resistance and prevents AR-V7-mediated feedback in advanced prostate cancer", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Chang Gung University", "source_org_type": "大学", "row_number": 385, "target_meta": "not available", "MOA_meta": "PROTAC"}, {"drug_name": "06-30", "company": "University of Arizona", "org_type": "大学", "target": "p47phox", "modality": "other", "importance_level": "中", "total_score": 50.5, "institution_score": 25, "track_score": 65, "milestone_score": 70, "field_heat_score": 60, "bonus_score": 4, "brief_reason": "06-30为首创p47phox激活剂，通过诱导ROS介导的氧化应激选择性杀伤AML细胞，机制新颖且具治疗窗。大学背景拉低机构分，但first-in-class机制+较强preclinical证据（体外/体内活性、机制验证）支撑中等重要性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8842", "id": "lVXM_5wBX1NQZOEH-LG6", "source_drug_name": "06-30", "title": "A novel thioxanthenone activates p47phox to exploit redox vulnerabilities in acute myeloid leukemia", "abstract_text": "Acute myeloid leukemia (AML) is an aggressive hematologic malignancy with poor outcomes, particularly among older adults and patients harboring adverse-risk features such as FLT3-ITD and p53 mutations. Relapsed or refractory (R/R) AML remains largely incurable, underscoring the urgent need for new therapies that selectively target leukemia-specific survival pathways while sparing normal hematopoiesis. Through a focused medicinal chemistry campaign, we optimized an understudied thioxanthenone chemotype and identified 06-30 as a potent lead compound with broad anti-AML activity. 06-30 induces robust and selective cytotoxicity across genetically diverse AML cell lines including models resistant to standard of care agents (cytarabine, azacitidine), and demonstrates strong activity in primary AML blasts with adverse molecular profiles. Unbiased integrative proteomic and transcriptomic analyses revealed p47phox (NCF1), a cytosolic organizer subunit of the NADPH oxidase complex, as the top common drug-induced target following 06-30 treatment with >9-fold increases in protein abundance and >50-fold increases in mRNA levels. Although p47phox is well established in host defense and inflammatory reactive oxygen species (ROS) generation, its role in AML pathogenesis and therapeutic sensitivity remains undefined. We hypothesize that p47phox functions as a pharmacodynamically regulated effector of 06-30 that drives ROS-mediated DNA damage and apoptosis in AML by exploiting leukemia-specific redox dysregulation. Supporting this hypothesis, shRNA-mediated silencing of p47phox significantly diminished 06-30-induced ROS generation and apoptosis and antioxidant co-treatment similarly blunted cell death. Importantly, 06-30 demonstrated selective toxicity toward AML cells while sparing normal CD34+ bone marrow progenitors, consistent with the enhanced antioxidant capacity of normal hematopoietic cells and establishing a clear therapeutic window. In vivo, 06-30 significantly extended overall survival and was very well tolerated. Ex vivo analyses demonstrated that its antileukemic efficacy was associated with increased p47phox expression and oxidative DNA damage as quantified by 8-oxoguanine levels. To our knowledge, no anticancer pharmacologic activators of p47phox have been previously described. Thus, thioxanthenone 06-30 represents both a first-in-class mechanistic probe and a promising therapeutic lead for redox-based targeting in AML. Together, these findings provide strong rationale for the further preclinical development and eventually clinical investigation of 06-30 as a strategy to exploit redox vulnerabilities in leukemia and improve outcomes for patients with limited therapeutic options.", "source_company": "University of Arizona", "source_org_type": "大学", "row_number": 410, "target_meta": "NCF1", "MOA_meta": "其他"}, {"drug_name": "CDK4-selective inhibitor", "company": "Broad Institute", "org_type": "研究机构", "target": "CDK4", "modality": "inhibitor", "importance_level": "中", "total_score": 50.5, "institution_score": 35, "track_score": 75, "milestone_score": 45, "field_heat_score": 65, "bonus_score": 0, "brief_reason": "CDK4-selective inhibitor显示对多种癌症（包括CDK6缺失或CDK4改变型）潜在治疗脆弱性，具有较高靶点和赛道热度。Broad Institute为顶级研究机构但非药企，缺乏明确药物开发里程碑和临床推进信息导致总体评分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3436", "id": "Op7ECZ0BZznHJdntvNYd", "source_drug_name": "CDK4-selective inhibitor", "title": "Unraveling determinants of drug response: PRISM viability profiling of hundreds of oncology therapeutics reveals mediators of selectivity and mechanism", "abstract_text": "Incomplete understanding of drug mechanism, selectivity, and polypharmacology can contribute to failed clinical trials. Drug candidates are generally characterized with limited pre-clinical tools and a narrow indication focus based on expected target biology. Using approaches such as large-scale PRISM profiling of 900 cell lines that have been genomically profiled in the Dependency Map coupled with machine learning analysis can provide a more thorough and agnostic understanding of oncology drugs. Here, we demonstrate that systematic characterization of an Oncology Reference library of over 250 oncology drugs, encompassing biologics (e.g., cytokines, antibody-drug conjugates), targeted protein degraders, and small molecules, of which two-thirds have never been tested with large-scale cell line profiling, enables better understanding of on-target and off-target effects. We developed models to quantify selectivity, on-target activity, and polypharmacology. Surprisingly, in some instances, these measures of cellular specificity can anticipate differential outcomes in clinical trials. Among unexpected findings, we identified a recurrent viability signature predictive of compound lysosomal accumulation, a phenomenon associated with phospholipidosis. In addition, CDK4-selective inhibition emerged as a potential therapeutic vulnerability across a diverse range of cancer types, including CDK6-deficient or CDK4-altered cancer. Our findings establish the Oncology Reference dataset and PRISM as a benchmark for evaluating current and emerging cancer therapies: combining large-scale systematic cell line profiling, genomic characterization, and machine learning analysis enables comprehensive characterization of oncology drugs with potential to inform clinical development.", "source_company": "Broad Institute", "source_org_type": "研究机构", "row_number": 420, "target_meta": "CDK4", "MOA_meta": "抑制剂"}, {"drug_name": "FGFR2 inhibitors", "company": "Osaka Metropolitan University Graduate School of Medicine", "org_type": "大学", "target": "FGFR2", "modality": "inhibitor", "importance_level": "中", "total_score": 50.5, "institution_score": 35, "track_score": 75, "milestone_score": 45, "field_heat_score": 65, "bonus_score": 0, "brief_reason": "FGFR2为实体瘤中重要靶点，抑制剂在胆道肿瘤已有临床验证且在食管/胃癌、乳腺癌中显示潜在价值。大学机构非主要研发主体、仅回顾性真实世界数据分析未达明确里程碑导致总分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3765", "id": "Qp7ECZ0BZznHJdntvNYd", "source_drug_name": "FGFR2 inhibitors", "title": "FGFR2 might be a promising therapeutic target for some types of carcinomas: Analysis of 1312 tumors with FGFR2 abnormalities", "abstract_text": "Background: Genetic abnormalities of the fibroblast growth factor receptor 2 (FGFR2) gene, including amplification, fusions, and mutations, have been reported in various solid tumors. While molecular targeted therapies against FGFR2 fusion have been proved to be useful in cholangiocarcinoma, the therapeutic significance of FGFR2 inhibitors remains unclear in other various solid cancers. Genomic and clinical information from solid tumor cancer gene panel testing cases is consolidated in the Center for Cancer Genomics and Advanced Therapeutics (C-CAT) database in Japan. This study aimed to utilize the C-CAT database to clarify the clinical-pathological significance of FGFR2 abnormalities.\nMaterials & Methods: A total of 101,231 patients with solid cancer have been registered in the C-CAT database between June 2019 and June 2025. Of the 101,231 cases, 1312 cases with FGFR2 gene abnormalities were analyzed. Tumor type distribution, co-mutations, and responses to FGFR inhibitors were evaluated. Disease control rate (DCR) was assessed in patients who received FGFR-targeted therapy.\nResult: FGFR2 alterations included amplification in 515 cases, fusion in 280 cases, and mutations in 568 cases. Their abnormalities were detected most frequently in the biliary tract (271 cases), esophagus/stomach (231 cases), and breast (211 cases). Amplification was frequent in the esophagus/stomach (205 cases) and breast (105 cases). FGFR2 fusions are frequently detected in the biliary tract (163 cases), followed by breast (21 cases), pancreas (13 cases). Mutations were frequent in the uterus (111 cases), breast (89 cases), and biliary tract (86 cases). Among 1312 FGFR2 alteration cases, FGFR2 inhibitors were administered in 85 cases. Of the 85 cases, DCR was achieved in 49 cases, 44 cases of which were biliary tract cancer.\nConclusions: FGFR2 might be a promising therapeutic target not only for cholangiocarcinoma with fusion but also for esophagus/stomach cancer and breast cancer with FGFR2 alterations.", "source_company": "Osaka Metropolitan University Graduate School of Medicine", "source_org_type": "大学", "row_number": 489, "target_meta": "FGFR2", "MOA_meta": "抑制剂"}, {"drug_name": "JNK-in-8", "company": "University of Chicago", "org_type": "大学", "target": "JNK", "modality": "inhibitor", "importance_level": "中", "total_score": 50.5, "institution_score": 35, "track_score": 65, "milestone_score": 55, "field_heat_score": 60, "bonus_score": 2, "brief_reason": "JNK-in-8为JNK抑制剂，用于多激酶组合策略抑制TNBC转移潜能并增敏化疗。大学机构分数较低，但组合机制针对耐药转移有一定创新，处于优化前临床阶段，整体中等重要性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6022", "id": "HFXM_5wBX1NQZOEH-LK6", "source_drug_name": "JNK-in-8", "title": "Pro-metastatic kinase network inhibition to treat drug-resistant triple-negative breast cancer", "abstract_text": "Metastatic triple-negative breast cancer (mTNBC) has high mortality rates and limited therapeutic options. Chemotherapy, the basis of standard approved therapy for mTNBC, targets rapidly dividing cells but fails to eliminate the stem-like cells that drive metastasis. While kinases are promising drug targets, single-kinase inhibitors have been largely ineffective in mTNBC due to tumor heterogeneity, drug resistance, and the absence of predictive biomarkers. Our strategy is to identify and target kinase networks in pro-metastatic tumor cells that are upregulated in drug-resistant cells or specifically targeted by physiological regulators of metastasis. We initially utilized this approach to overcome AKT resistance in mTNBC. Employing a kinase activity assay (MIB-MS profiling), we demonstrated upregulation of Src family and ATM/ATR kinase networks following treatment of patient-derived, drug-resistant mTNBC organoids with the AKT inhibitor capivasertib. Sequential administration of capivasertib and dasatinib to target the Src family did not reduce organoid viability but did disrupt organoid formation and self-renewal, suggesting effective inhibition of metastatic potential. Building on our previous work, we then optimized a multi-kinase inhibitor regimen that mimics a physiological metastasis suppressor by targeting key stress-responsive kinase networks (ERK1/2, p38, JNK, and MLK). This low-dose drug combination (4MAPKi) prevented both TNBC metastasis and activation of compensatory pathways. We further refined this to a three-drug regimen (Ralimetinib, JNK-in-8, and Trametinib) that inhibits stress kinase networks, pro-motility gene expression and TNBC cell invasion in organoid assays. Importantly, combining this antimetastatic regimen with standard chemotherapy sensitized both TNBC cells and organoids to treatment. Ongoing studies focus on optimizing treatment efficacy with antibody-drug conjugates, characterizing kinase network targets specific for other metastasis regulators such as transcription factors, and exploring kinase networks as biomarkers for treatment resistance. Our long-term goal is to develop a low-toxicity, multi-kinase inhibitor strategy that reprograms metastatic TNBC cells, enhancing the efficacy and durability of their response to chemotherapy and improving clinical outcomes.", "source_company": "University of Chicago", "source_org_type": "大学", "row_number": 507, "target_meta": "JNK", "MOA_meta": "抑制剂"}, {"drug_name": "CDK4/6 inhibitors", "company": "Yonsei University College of Medicine", "org_type": "大学", "target": "CDK4/6", "modality": "inhibitor", "importance_level": "中", "total_score": 50.5, "institution_score": 35, "track_score": 75, "milestone_score": 40, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "该研究针对成熟靶点CDK4/6的耐药机制，利用单细胞核测序和空间转录组学进行深入探索，属于经典靶点在乳腺癌领域的机制研究。机构为大学，赛道热度中等偏高，但无新药开发里程碑，整体重要性中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/2959", "id": "JFXM_5wBX1NQZOEH-LK6", "source_drug_name": "CDK4/6 inhibitors", "title": "Mechanisms of resistance to CDK4/6 inhibitors: Insights from single-cell nucleus sequencing and spatial transcriptomics", "abstract_text": "Breast cancer incidence is increasing worldwide and represents the second most common malignancy in women after lung cancer. Among its subtypes, luminal B accounts for 10-20% of cases and shows a faster proliferation rate. Also, a poorer prognosis than luminal A, with a 5-year survival rate of only 32% at stage 4. Luminal B tumors are characterized by active estrogen receptor signaling and high expression of proliferation-associated genes such as Ki-67 and E2F, leading to enhanced estrogen-driven cell cycle progression. Consequently, CDK4/6 inhibitors, which block the G1 to S phase transition, have shown favorable therapeutic outcomes. However, in a subset of patients, treatment with CDK4/6 inhibitors induces a luminal-to-basal-like phenotypic conversion, which is associated with poor clinical prognosis. To elucidate the mechanism underlying this phenotype, we performed single-nucleus RNA sequencing and spatial transcriptomic analyses on paired pre- and post-treatment tumor biopsies from three patients who exhibited poor responses to CDK4/6 inhibition. After UMAP projection and batch correction, cell type annotation revealed no major changes in the overall cellular composition, with epithelial/tumor cells remaining dominant. Differential expression analysis showed minimal transcriptional changes in endothelial and fibroblast cells but substantial alterations in tumor/epithelial and immune cell populations. Focusing on immune cells, which displayed the largest number of DEGs, subclustering analysis revealed a marked post-treatment increase in innate lymphoid cells (ILCs), while overall immune cell numbers decreased following treatment. Cell-type-specific DEG analysis further identified substantial transcriptional reprogramming within plasma cells, CD4⁺, and CD8⁺ T cells. In parallel, tumor/epithelial cells exhibited distinct subtype redistribution after CDK4/6 inhibition, which is currently under detailed characterization. Spatial transcriptomic mapping based on nucleus-seq-derived cell type signatures is underway to visualize cell-type distribution and microenvironmental remodeling before and after treatment. Collectively, our integrative analyses aim to uncover the mechanisms of CDK4/6 inhibitor resistance, highlighting the potential roles of ILC expansion, immune remodeling, and epithelial plasticity in luminal-to-basal transition, and to identify biomarkers predictive of therapeutic response.", "source_company": "Yonsei University College of Medicine", "source_org_type": "大学", "row_number": 513, "target_meta": "CDK4,CDK6", "MOA_meta": "抑制剂"}, {"drug_name": "membrane-tethered engineered cytokine agonists", "company": "City of Hope National Medical Center", "org_type": "医院", "target": "未披露", "modality": "other", "importance_level": "中", "total_score": 50.5, "institution_score": 35, "track_score": 75, "milestone_score": 45, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "MECA为膜锚定工程化细胞因子激动剂，通过局部提供IL2样信号增强CAR-T细胞抗实体瘤活性，避免系统IL2毒性。机构为医院非商业研发、处于早期in vitro+初步体内阶段但显示优于对照的潜力，导致总分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9365", "id": "RlXM_5wBX1NQZOEH-LK6", "source_drug_name": "membrane-tethered engineered cytokine agonists", "title": "Improving antitumor T cell therapy with membrane-tethered engineered cytokine agonists", "abstract_text": "Chimeric antigen receptor (CAR) T cell therapy has demonstrated marked success in the control of hematological malignancies. However, the hostile milieu and chronic antigen exposure in the tumor microenvironment contribute to the induction of exhaustion and loss of efficacy of CAR T cells in the treatment of solid tumors.\nOvercoming T cell exhaustion is essential for improving immunotherapeutic efficacy in the treatment of solid tumors. One strategy focuses on engineering CAR T cells that generate a supportive local immune environment through expression of activation and survival-promoting proteins. Specifically, interleukin-2 (IL2) is an attractive candidate as it is a potent stimulator of proliferation and effector function in T cells. However, the therapeutic application of systemic IL2 is associated with life-threatening complications and T cell exhaustion. To address these toxicities, we have developed membrane-tethered engineered cytokine agonists (MECAs), which are cell-surface constrained proteins that transduce a defined subset of cytokine-mediated signals to promote T cell function without toxicity or T cell exhaustion.\nHere, we evaluate the influence of MECAs on the proliferation and cytotoxicity of CAR T cells in a glioblastoma-targeting model. IL13Rα2-targeting CAR T cells co-expressing the MECAs demonstrated improved cytotoxic function and proliferation in recursive challenge in in vitro models. Preliminary results demonstrate that MECA-expressing CAR T cells are not toxic in an in vivo orthotopic glioma model. Additionally, the CAR T cells co-expressing MECA had greater anti-tumor activity compared to CAR only T cells.\nExhaustion of antigen-specific T cells is a central challenge across multiple cancer immunotherapy modalities. The proposed MECAs have the potential to revolutionize immunotherapy by providing effective and widely applicable orthogonal signals that improve the proliferation and effector activity of adoptively transferred CAR T cells.", "source_company": "City of Hope National Medical Center", "source_org_type": "医院", "row_number": 531, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "IL-12 saRNA-LNP", "company": "BC Cancer Research Institute / BC Cancer Research Centre", "org_type": "研究机构", "target": "IL-12", "modality": "saRNA", "importance_level": "中", "total_score": 50.5, "institution_score": 35, "track_score": 75, "milestone_score": 45, "field_heat_score": 60, "bonus_score": 2, "brief_reason": "通过肝细胞表达IL-12的saRNA-LNP激活抗肿瘤免疫，与优化伊立替康脂质体联合改善免疫抑制性肺转移黑色素瘤模型。研究机构背景+preclinical组合疗效数据导致中等重要性评分。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5171", "id": "kVXM_5wBX1NQZOEH-LK6", "source_drug_name": "IL-12 saRNA-LNP", "title": "Combining an optimized irinotecan formulation with self-amplyfing RNA to treat an immunosuppressive lung metastasis melanoma model", "abstract_text": "Background: Melanoma is an aggressive skin cancer that frequently metastasizes to the lungs in its advanced stages. The tumor microenvironment of melanoma is typically immunosuppressive; lacking immune cells with strong antitumor activity. While interleukin-12 (IL-12) based immunotherapy has shown potential for treating melanoma, its clinical application is limited by significant toxicity. To address this, we are developing a self-amplifying RNA (saRNA)-lipid nanoparticle (LNP) system to produce IL-12 in vivo. The formulation selected is similar to that used for Onpattro, a clinically approved formulation of siRNA designed to deliver RNA to liver hepatocytes. IL-12 saRNA delivery to hepatocytes will increase plasma levels of IL-12 and sustain expression which should stimulate an immune response. This saRNA LNP formulation is being combined with a novel liposomal formulation of irinotecan (Irinosome High C). This formulation can improve the tumor immune microenvironment (TIME)from an immunosuppressive one to an immunosupportive one. We believe that this formulation is ideally suited for combination with IL-12 saRNA-LNPs.\nMethod: The safe and effective (as judged by IL-12 levels on the plasma) dose of saRNA-LNPs was determined in C57BL/6 mice following intravenous (iv) administration. A safe and effective (as judged by assessments of anti-tumor activity) was determined for Irinosome High C following iv administration. These treatments were used alone and in combination to treat a model lung metastasis model where mice were injected iv with B16F10 melanoma cells. Tumor burden in the lungs was determined 18 days after cell injection (6 days after last treatment) and overall survival data was collected along with health status data. As a function of time after treatments splenocytes from mice were isolated and co-cultured with B16F10 cells in vitro and immune mediated cell kill was determined.\nResults: The combination of IL-12 saRNA-LNP and Irinosome High C significantly improved survival and reduced lung tumor burden in B16 tumor bearing mice compared to those receiving either treatment alone. Splenocyte assays confirmed that IL-12 treatment enhanced levels of key immune cytokines, including IL-12, IL-2, and IFN-γ, indicating a robust antitumor immune response.\nConclusion: The combination of Irinosome High C and IL-12 saRNA-LNPs represents a promising new approach for treating lung metastatic disease a life-threatening complication seen in patients with late-stage melanoma. This strategy may offer a safer, more effective treatment option through use of a TIME modulatory agent with IL-12 mediated immune activation. Studies are on going to better understand the underlying mechanisms driving enhanced antitumor responses and the development of strategies to see this approach transition in various tumor models and from the lab to patients.", "source_company": "BC Cancer Research Institute\nBC Cancer Research Centre", "source_org_type": "研究机构", "row_number": 580, "target_meta": "IL-12", "MOA_meta": "saRNA疗法"}, {"drug_name": "FTO-43N", "company": "UC San Diego", "org_type": "大学", "target": "FTO", "modality": "inhibitor", "importance_level": "中", "total_score": 50.5, "institution_score": 35, "track_score": 75, "milestone_score": 45, "field_heat_score": 65, "bonus_score": 2, "brief_reason": "FTO-43N为选择性FTO小分子抑制剂，靶向m6A去甲基化酶FTO以抑制GBM干细胞特性。大学早期发现+lead优化阶段，m6A调控赛道在肿瘤干细胞领域有一定热度，但机构非商业化主体且仍处preclinical导致总分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6418", "id": "n1XM_5wBX1NQZOEH-LK6", "source_drug_name": "FTO-43N", "title": "Regulating m6A-RNA modification as new therapies for cancer", "abstract_text": "The role of post-transcriptional modifications of mRNA in regulation of gene expression, stem-cell maintenance, and differentiation has gained significant interest. Transcriptome-wide mapping has revealed that the most abundant internal mRNA modification is the N6-methyladenosine (m6A), which is present in > 25% of all mRNAs. The N6-methylation of adenosine is a reversible modification controlled by a multiprotein complex comprised primarily of METTL3 and METTL14, which is responsible for the methylation step, and by two Fe(II)-α-ketoglutarate-dependent dioxygenases, ALKBH5 and FTO, which drive the reverse, demethylation step. In addition, FTO, but not ALKBH5, is responsible for the demethylation of N6, 2’-O-dimethyladenosine (m6Am), a prevalent modification frequently found at the 5′ cap-adjacent adenosine of mRNA where it plays a critical role in controlling mRNA stability and translation. In GBM, reduced levels of m6A and m6Am are involved in cell proliferation, survival, and differentiation. As such pathways are known to be directly linked to acquisition of stem-like cell properties in GBM and other solid and hematological tumors, m6A dysregulation is believed to play a role in the generation of stem-like tumor initiating cells and tumorigenesis where such properties are known to be important for tumor progression, recurrence, and resistance. In GSCs, knockdown of the m6A demethylases FTO and its homolog ALKBH5 suppresses GSC-induced tumorigenesis. Moreover, FTO inhibition prolongs lifespan in tumor bearing mice. Recently, we identified novel inhibitors of FTO that impaired sphere formation of GSCs in 3D organoid models in a manner comparable to FTO silencing. Further medicinal chemistry efforts in this area led to the discovery of a novel series of drug-like small molecules, exemplified by the oxetane derivative FTO-43N that selectively inhibit FTO over ALKBH5. These molecules act as competitive inhibitors of FTO and demonstrate potent antiproliferative effects in glioblastoma. These promising results indicate that selective inhibition of FTO could be an effective strategy to target the resistant stem-cell populations in GBM. Furthermore, assessment of in vitro safety pharmacology (CEREP SafetyScan) and brain/plasma PK suggest that FTO-43N and related compounds are an attractive selective FTO inhibitors as drug candidates for the treatment of GBM. Accordingly, using structure-based design strategies combined with advanced in vitro and in vivo modeling systems, lead-optimization studies to identify candidate FTO inhibitors with pharmacokinetic (PK), in vivo efficacy, and safety/tolerability profiles suitable for further drug development.", "source_company": "UC San Diego", "source_org_type": "大学", "row_number": 587, "target_meta": "FTO", "MOA_meta": "抑制剂"}, {"drug_name": "CYD-2-11", "company": "Emory University", "org_type": "大学", "target": "Bax", "modality": "inhibitor", "importance_level": "中", "total_score": 50.5, "institution_score": 35, "track_score": 75, "milestone_score": 45, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "CYD-2-11为小分子Bax激动剂，直接靶向Bax S184结构域激活其促凋亡活性，并诱导cGAS-STING通路增强免疫。机构为大学非企业导致institution_score较低，但Bax激活作为潜在新机制+免疫协同在KRAS肺癌中有一定preclinical强度，总分处于中位。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9438", "id": "q1XM_5wBX1NQZOEH-LK6", "source_drug_name": "CYD-2-11", "title": "Bax activation promotes immune activity and synergizes with PD-L1 blockade immunotherapy against mutant KRAS-driven lung cancer", "abstract_text": "The mutant KRAS-driven non-small cell lung cancers (NSCLC) frequently co-occurring mutations of LKB1 or p53 exhibit varying degrees of resistance to conventional treatments and anti-PD-L1 immunotherapy. It is urgently needed to develop new strategies to improve the outcome of these diseases. We have recently discovered that small molecule Bax activator CYD-2-11 targets the S184 structural pocket in the C-terminal tail of Bax, thereby activating its proapoptotic activity with potent antitumor activity against lung cancer. Here we further found that, in addition to apoptotic cell death, CYD-2-11 also induces cytosolic DNA and activation of cGAS-STING-TBK1-IRF3 pathway, thereby upregulating PD-L1 and producing interferons (IFN alpha and IFN beta) and chemokines (CCL5 and CXCL10). The combination of CYD-2-11 with anti-PD-L1 synergistically enhances intratumor CD3+ total T cells, CD8+ cytotoxic T cells and CD44+ memory/effector T-cells in association with reduction of regulatory T cells (Tregs), exhausted CD8+T cells and Gr-1+ CD11b+ and CD49d+ MDSCs, which contribute to increased immunity leading to the synergistic suppression of lung tumor growth and prolonged survival in genetically engineered mutant KRAS-driven lung cancer mouse models that are resistant to anti-PD-L1 immunotherapy. These findings provide preclinical evidence for the mechanism-driven combination of small molecule Bax activator with anti-PD-L1 as an effective strategy for lung cancer therapy, especially for those mutant KRAS-driven lung cancers that are resistant to PD-L1 blockade immunotherapy.", "source_company": "Emory University", "source_org_type": "大学", "row_number": 598, "target_meta": "BAX", "MOA_meta": "抑制剂"}, {"drug_name": "Silicon quantum dots", "company": "Applied Quantum Materials, Inc.", "org_type": "公司", "target": "未披露", "modality": "other", "importance_level": "中", "total_score": 50.5, "institution_score": 45, "track_score": 65, "milestone_score": 40, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "Silicon quantum dots作为无重金属、光稳定、光敏剂用于癌症光动力疗法（PDT），通过NIR激光产生ROS杀伤癌细胞，但靶点未明确披露。AQM为中小型纳米材料初创公司，处于体外preclinical阶段，赛道有创新但非主流热门，综合潜力中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9325", "id": "01XM_5wBX1NQZOEH-LK6", "source_drug_name": "Silicon quantum dots", "title": "Cancer photodynamic therapy: Silicon quantum dots as therapeutic nanomaterials", "abstract_text": "Cancer photodynamic therapy (PDT) is a minimally invasive cancer treatment that uses photosensitizers to generate reactive oxygen species (ROS) and induce selective tumor cell death. Conventional PDT agents, including organic dyes and metal-based nanoparticles, face significant limitations such as photobleaching, poor tissue penetration, toxicity, and limited photostability which restrict their clinical effectiveness. Silicon quantum dots (SiQDs) offer a new alternative of photosensitizers that can overcome these limitations. The nanomaterials have already shown strong potential in cancer detection and diagnostics. In addition, SiQDs are also ideal PDT agents because they are heavy-metal-free, non-toxic, biocompatible, photostable, and exhibit tunable optical properties with customizable surfaces for targeted delivery, enhanced precision and therapeutics. Applied Quantum Materials Inc. (AQM) synthesizes SiQDs that are highly-pure, have a narrow-size-distribution and showcase exquisite control over surface modifications (including biomolecule conjugation of 8-150 kDa). These nanomaterials display bright, size-dependent luminescence across the visible-NIR spectrum. Biocompatibility studies show >90% cell viability at concentrations up to 500 µg/mL after 24 h incubation, indicating SiQDs have great potential for clinical translation. AQM’s recent advances have shown enhanced material uptake into cancer cells along with improved light-triggered therapeutic activity. Under low-level NIR laser irradiation, findings exhibited significantly reduced cancer cell viability, correlating with increased intracellular ROS generation. Initial results indicate cancer cells destruction in 10 minutes. These outcomes offer great potential for SiQDs as effective photosensitizers for PDT.", "source_company": "Applied Quantum Materials, Inc.", "source_org_type": "公司", "row_number": 624, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "CDK4/6 inhibitors", "company": "Baylor College of Medicine", "org_type": "大学", "target": "CDK4/6", "modality": "inhibitor", "importance_level": "中", "total_score": 50.5, "institution_score": 35, "track_score": 75, "milestone_score": 40, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "CDK4/6抑制剂为成熟靶向药物，主要用于ER+/HER2-乳腺癌，但本摘要聚焦MCM2/LC作为耐药生物标志物而非新药开发。大学机构+成熟赛道+回顾性生物标志物研究导致总体中等重要性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1189", "id": "1VXM_5wBX1NQZOEH-LK6", "source_drug_name": "CDK4/6 inhibitors", "title": "MCM2 and the origin licensing complex: A putative node of ER+/HER2- breast cancer therapy resistance", "abstract_text": "Background: The use of CDK4/6 inhibitors (CDK4/6i) in combination with endocrine therapy (ET) has revolutionized treatment practices for advanced and high-risk ER+/HER2- breast cancer (BC) via effective inhibition of cell cycle activation. However, the vast majority of patients eventually progress on these therapies, underscoring the need for new treatment strategies to select patients, monitor response, and target novel therapeutic vulnerabilities. We previously reported that high expression of MCM2 and its origin licensing complex (LC) is enriched in primary tumors refractory to CDK4/6i (SABCS22-P2-03-10). LC factors are transcriptionally regulated by E2F/MYC-driven programs, which are activated by diverse drivers of resistance. We propose that MCM2/LC expression may be a biomarker reflecting multiple ET and CDK4/6i resistance mechanisms, due to its role in cell cycle activation.\nMethods: A retrospective review was conducted on a real-world, treatment-naive ER+/HER2- BC cohort of 1,960 largely metastatic patients with biopsies from breast or other sites (~50% each) that underwent NGS profiling (DNA: 592-gene panel/whole-exome; RNA: whole-transcriptome) at Caris Life Sciences. Tumors were stratified by MCM2 or LC gene set mRNA into Q4 (high) versus Q1 (low; n=490 each), balanced for ET/CDK4/6i exposure, MSI-H, and TMB-H. Histology, PAM50, mutations (mut), gene amplifications(amp) and deletions(del), and differential gene expression were analyzed. Chi-square, Fisher’s Exact, or Mann-Whitney U tests were performed with Benjamini-Hochberg FDR for molecular variables (q<0.05).\nResults: MCM2-high vs -low tumors were LumB-dominant (LumB 85.5% vs 39.8%; LumA 5.3% vs 56.3%, p<1e-63) with less lobular histology (6.1% vs 17.1%, p=0.0001). Transcriptomically, PI3K/AKT/mTOR, E2F/MYC targets, G2M checkpoint, and DNA repair hallmark pathways were enriched in MCM2-high (all FDR q<0.05). Genomically, MCM2-high harbored a higher frequency of TP53mut (32.6% vs 16.6%, q=4e-6), RB1mut (5.8% vs 1.2%, q=0.052), CCND1amp (26% vs 6%, q=4.5e-11), FGF3/4/19amp (~25% vs ~6%, q≤2.2e-10), MYCamp (5.4% vs 0.8%, q=0.0136), and CDKN2A/Bdel (CDKN2A 29.3% vs 15.5%, q=6.9e-4; CDKN2B 17.5% vs 7.3%, q=1.38e-3). Notably, MCM2 and MKI67 gene expression were highly correlated (Spearman’s ρ=0.77, p<0.05). Very similar results were found for LC-high vs -low tumors.\nConclusions: In ER+/HER2- BC, high MCM2/LC is associated with LumB subtype, E2F/MYC and cell cycle activation, selection of TP53 and RB1 mutations, and CCND1/MYC/FGF amplifications. Our findings suggest that MCM2 or LC mRNA may act as a surrogate marker for a network of oncogenic pathways previously identified to drive endocrine and CDK4/6i resistance. Future studies will evaluate MCM2/LC beyond proliferation, as a predictive biomarker for CDK4/6i-based regimens, as we have previously shown in the primary ET-treated setting (SABCS24-P1-03-20).", "source_company": "Baylor College of Medicine", "source_org_type": "大学", "row_number": 626, "target_meta": "CDK4,CDK6", "MOA_meta": "抑制剂"}, {"drug_name": "PR5-LL-CM01", "company": "Indiana University Melvin and Bren Simon Comprehensive Cancer Center", "org_type": "研究机构", "target": "PRMT5", "modality": "inhibitor", "importance_level": "中", "total_score": 50.5, "institution_score": 35, "track_score": 75, "milestone_score": 45, "field_heat_score": 65, "bonus_score": 2, "brief_reason": "药物为PRMT5小分子抑制剂，针对PDAC中NF-κB信号通路发挥抗肿瘤作用。机构为大学附属癌症研究中心非商业化主体、仍处体内研究前阶段导致总分中等，但PRMT5在肿瘤领域有一定关注度。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11122", "id": "OFXM_5wBX1NQZOEH-LO6", "source_drug_name": "PR5-LL-CM01", "title": "Investigating the therapeutic potential of a nanocrystal PRMT5 inhibitor in pancreatic ductal adenocarcinoma", "abstract_text": "Persistent inflammation is a defining feature of pancreatic ductal adenocarcinoma (PDAC), largely driven by sustained activation of the NF-κB signaling pathway. Disruption of NF-κB regulatory mechanisms contributes significantly to this chronic activation. Protein arginine methyltransferase 5 (PRMT5), a known promoter of tumorigenesis in several cancers, including PDAC, colorectal, and breast, has emerged as a promising therapeutic target. Clinical data reveal that PDAC patients with high PRMT5 expression have significantly shorter median survival, underscoring its prognostic and therapeutic relevance. Our lab has been developing small-molecule inhibitors targeting PRMT5. Among these, our patented compound, PR5-LL-CM01 (CM01), has shown superior anti-tumor efficacy and reduced toxicity in PDAC models compared to the commercially available PRMT5 inhibitor EPZ015666. However, CM01’s poor water solubility poses a challenge for clinical translation. To address this, we aim to enhance its water dispersibility and bioavailability by formulating CM01 as an albumin-coated nanocrystal (NC) (Abxtal). Preliminary studies confirmed successful production and physicochemical characterization of CM01 NCs, which have an optimized particle size (Z-average ~87 nm) and can be stored at -20ºC as lyophilized solid for at least three months. In this project, we assess the therapeutic potential of CM01 NC in vitro and in vivo. We hypothesize that CM01 NC more effectively inhibits PRMT5-mediated NF-κB signaling and associated oncogenic processes than unformulated CM01, and that it synergizes with gemcitabine (Gem) to suppress PDAC progression. Supporting this hypothesis, CM01 NC showed equal or greater inhibition of PDAC PANC1 and MIA PaCa2 cell growth compared to CM01, and more effectively suppressed 3D spheroid growth and cell migration in vitro. CM01 NC also outperformed CM01 in reducing NF-κB transcriptional activity, with comparable reductions in NF-κB target genes (TNF-α and IL-8) per qPCR assays. Additionally, Chou-Talalay analysis demonstrated that CM01 NC exhibits synergistic activity with Gem. We are now transitioning to in vivo studies to evaluate the pharmacokinetics and therapeutic efficacy of CM01 NC, both as a monotherapy and in combination with Gem, using PDAC models. This study may establish CM01 NC, alone or with Gem, as a promising therapeutic strategy, and could lay the foundation for clinical development of CM01 NC-based treatments for PDAC.", "source_company": "Indiana University Melvin and Bren Simon Comprehensive Cancer Center", "source_org_type": "研究机构", "row_number": 691, "target_meta": "PRMT5", "MOA_meta": "抑制剂"}, {"drug_name": "PI3Kγ inhibitor", "company": "University of California, San Diego", "org_type": "大学", "target": "PI3Kγ", "modality": "inhibitor", "importance_level": "中", "total_score": 50.5, "institution_score": 35, "track_score": 75, "milestone_score": 45, "field_heat_score": 65, "bonus_score": 0, "brief_reason": "靶向PI3Kγ的抑制剂，通过阻断髓系细胞免疫抑制信号，与αvβ8抑制联合可显著改善肿瘤微环境并实现持久抑瘤。大学机构得分较低，但PI3Kγ在免疫抑制中的机制研究较新颖且有临床前联合潜力，整体处于中等重要性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9418", "id": "bFXM_5wBX1NQZOEH-LO6", "source_drug_name": "PI3Kγ inhibitor", "title": "Combined inhibition of myeloid cell PI3Kγ and regulatory T cell integrin αvβ8 promotes durable tumor suppression", "abstract_text": "The immunosuppressive tumor microenvironment (TME) remains a critical barrier to effective immunotherapy. Immune suppressive myeloid cells and regulatory T cells can each prevent effective anti-tumor immune responses. The integrin αvβ8 promotes immune evasion by serving as a key activator of latent TGF-β in regulatory T cells, while the lipid kinase PI3Kγ promotes immunosuppressive signaling in myeloid cells. Genetic and pharmacological inhibition of PI3Kγ stimulates integrin αvβ8 expression on regulatory T cells both in mouse models of cancer and in patients enrolled in cancer clinical trials. Inhibition of either αvβ8 or PI3Kγ significantly suppressed head and neck tumor growth, suggesting they each play important roles in modulating anti-tumor immunity. To gain mechanistic insights into the impacts of these therapeutic approaches, we performed single-cell RNA sequencing (scRNA-seq) on HPV+ HNSCC tumors from wild-type (WT) and PI3Kγ knockout (KO) mice, with or without anti-αvβ8 treatment, to investigate the individual and combined impacts of PI3Kγ inhibition and αvβ8 blockade in the TME. RNA velocity and cell-cell communication inference analysis was performed to uncover dynamic regulatory interactions among cell populations. Antagonism of integrin αvβ8 led to increased CD8+ T cell infiltration and a reduction in TGF-β-responsive transcriptional programs. PI3Kγ inhibition promoted a proinflammatory shift in myeloid cells, characterized by diminished M2-like polarization and enhanced antigen presentation, and increased CD8+ T cell recruitment. Together combined inhibition of αvβ8 and PI3Kγ reversed T cell exclusion and promoted durable tumor suppression.", "source_company": "University of California, San Diego", "source_org_type": "大学", "row_number": 722, "target_meta": "PI3Kγ", "MOA_meta": "抑制剂"}, {"drug_name": "KC12", "company": "Shenyang Pharmaceutical University", "org_type": "大学", "target": "Pim/Mnk", "modality": "inhibitor", "importance_level": "中", "total_score": 50.5, "institution_score": 35, "track_score": 55, "milestone_score": 65, "field_heat_score": 60, "bonus_score": 2, "brief_reason": "KC12为新型选择性双Pim/Mnk抑制剂，靶向白血病中cap-dependent翻译关键激酶。大学机构背景限制分数，但化合物优化后活性/选择性/PK/动物模型疗效清晰，具备进一步开发价值。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4401", "id": "lVXM_5wBX1NQZOEH-LO6", "source_drug_name": "KC12", "title": "Development of the pyridopyrimidine derivative KC12 as a selective dual Pim/Mnk inhibitor to inhibit leukemia cell growth", "abstract_text": "Myeloid leukemia is an abnormal proliferative disease relying on fast cap-dependent protein translation. Both provirus integration in Maloney murine leukemia virus (Pim) kinases and mitogen-activated protein kinase-interacting kinases (Mnk) play key roles in activating cap-dependent translation, making them attractive targets for anticancer drug development. Although several selective Pim or Mnk inhibitors entered clinical trials, their efficacy was limited. We propose that concurrent inhibition of both Pim/Mnk kinases is necessary for effective treatment. Previously, we reported the first dual Pim and Mnk inhibitor 21o with a pyrido[3,2-d]pyrimidine core (IC50 Mnk1: 9 nM, Mnk2: 5 nM, Pim1: 120 nM), but suffered from poor solubility. We optimized 21o based on molecular docking and obtained a compound KC12 with enhanced kinase inhibitory activity (IC50 Mnk1:32 nM, Mnk2 3 nM; Pim 1 32 nM) and improved selectivity (only 4 out of 42 tested kinases showed >40% inhibition at 100 nM). KC12 exhibits increased aqueous solubility and superior anti-proliferative activity compared to 21o, as well as to the Pim inhibitor TP-3654 and the Mnk inhibitor eFT508. KC12 induced G0/G1 phase cell cycle arrest in K562 cells and apoptosis in MOLM-13 cells, correlated to the suppression of both eIF4E and 4EBP1 phosphorylation, and the cap-dependent translation products c-Myc and Mcl-1. Moreover, KC12 demonstrated a more favorable pharmacokinetic profile than 21o and exhibited enhanced antitumor efficacy in MOLM-13 xenograft models. These findings suggest that KC12 acts as a novel, potent, and selective dual Pim/Mnk inhibitor and is worthy of further development as a therapeutic agent.", "source_company": "Shenyang Pharmaceutical University", "source_org_type": "大学", "row_number": 749, "target_meta": "PIM,MNK", "MOA_meta": "抑制剂"}, {"drug_name": "Her2CAR macrophages", "company": "University of California, Santa Barbara", "org_type": "大学", "target": "HER2", "modality": "CAR", "importance_level": "中", "total_score": 50.5, "institution_score": 35, "track_score": 75, "milestone_score": 45, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "HER2靶向的CAR巨噬细胞（CAR-M）通过持续trogocytosis机制诱导实体瘤细胞延迟凋亡，在3D模型中显示肿瘤球体显著缩小。大学早期研究阶段，赛道具潜力但公司实力一般，整体中等重要性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4610", "id": "Y1XM_5wBX1NQZOEH-LS6", "source_drug_name": "Her2CAR macrophages", "title": "Bites that kill: Understanding cancer cell fate after macrophage mediated trogocytosis", "abstract_text": "Macrophage therapies are an exciting avenue for targeted cancer cell killing in tumors. Macrophages phagocytose (that is, whole cell engulfment) of dying, dead, and abnormal cells. However, it’s been observed that in solid tumors, macrophages primarily perform trogocytosis or nibbling, where they tear away portions of solid tumor cells. Trogocytosis in tumors is observed to be paradoxical: while it allows immune cells to strip away antigen from the cancer cell surface and thus allowing cancer progression. Conversely, it can cause cancer cell death, aiding immunotherapy. This dichotomous result raises the question of how to leverage trogocytosis in immunotherapy to be consistently lethal. We observe higher rates of trogocytosis compared to phagocytosis with Chimeric Antigen Receptor macrophages (CAR-M) when interacting with solid tumor cells. Our 3D tumor spheroid model constructed with SKOV3 cells shows a significant reduction in size with Her2CAR macrophages, with higher trogocytosis. I observe trogocytosed cancer cells to undergo apoptotic cell death via specific targeting by Her2CAR macrophages in 2D cell cultures. However, interestingly, death is not immediate in the co-cultures; instead, it happens following sustained trogocytic attack. In the first 2 hours of co-culture, when trogocytosis is significantly higher than phagocytosis, there's no cancer cell death. Our 3D tumor spheroid model also shows a reduction in spheroid diameter with Her2CAR macrophages after 5 days of co-culture. The cancer cell death can be blocked with a pan-caspase inhibitor Q-VD-Oph. The delayed cancer death suggests that trogocytosed cancer cells overcome initial, non-lethal loss of cell membrane; however, continual trogocytic attack renders cancer cells susceptible to apoptosis at later timepoints. Continuous loss of the cell membrane, followed by continual repair while maintaining homeostasis, is an energy-expensive process for the cancer cells. Thus accumulation of sustained stress in the trogocytosed cancer cells can ultimately push them to undergo apoptosis. I am currently investigating oxidative stress accumulation for activation of apoptosis in trogocytosed cells. Further, a change in transcriptomic profile for certain genes following 3-day co-culture with Her2CAR macrophages is also observed, suggesting the trogocytosed cells can alter their transcriptomic response to trogocytosis. Under current investigation is whether accumulated stress in trogocytosed cells causes this change in transcriptomic profile. CAR-M presents a promising avenue for targeting tumors. However, their efficacy in solid tumors needs to be improved. We observe continual trogocytosis pushes cancer cells to apoptosis at later timepoints. Thus, to make trogocytosis lethal in immunotherapy, understanding the trogocytosed cell response and investigating the fate of trogocytosed cells is essential.", "source_company": "University of California, at Santa Barbara\nUniversity of California, Santa Barbara", "source_org_type": "大学", "row_number": 899, "target_meta": "HER2", "MOA_meta": "其他"}, {"drug_name": "TRAIL mRNA", "company": "University of Alberta", "org_type": "大学", "target": "TRAIL receptor (death-receptor pathways)", "modality": "mRNA", "importance_level": "中", "total_score": 50.5, "institution_score": 35, "track_score": 75, "milestone_score": 45, "field_heat_score": 65, "bonus_score": 2, "brief_reason": "TRAIL mRNA通过激活死亡受体通路诱导NSCLC细胞凋亡，采用大学自研的可降解阳离子脂聚物递送系统并联合siRNA增强抗凋亡抵抗。机构为大学非商业化开发、仍处细胞水平研究导致总体分偏中，但mRNA+siRNA组合策略在热门核酸治疗赛道有一定创新潜力。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4007", "id": "dlXM_5wBX1NQZOEH-LS6", "source_drug_name": "TRAIL mRNA", "title": "Polymeric delivery of TRAIL mRNA for inducing apoptosis in non-small cell lung cancer", "abstract_text": "Tumor necrosis factor-related apoptosis-inducing ligand (TRAIL) activates death-receptor pathways to trigger caspase-dependent apoptosis, yet recombinant TRAIL has demonstrated limited activity in non-small cell lung cancer (NSCLC) because of rapid clearance and apoptotic resistance. Delivering TRAIL as messenger RNA (mRNA) may overcome these limitations, but mRNA therapeutics remain limited in oncology due to delivery inefficiencies, instability, and incomplete cytosolic release. This study evaluated biodegradable cationic lipopolymers for TRAIL mRNA delivery and examined whether combining TRAIL mRNA with small interfering RNAs (siRNAs) targeting anti-apoptotic mediators could strengthen apoptotic responses in resistant NSCLC settings. Biodegradable cationic lipopolymers were screened based on their delivery profiles. Nanoparticles were characterized by hydrodynamic diameter, zeta potential, and transmission electron microscopy (TEM). A549 lung adenocarcinoma cells were used for mechanistic studies, including multi-day viability assays, caspase-3/7 activity using the Caspase-Glo assay (24-72 hours), mitochondrial membrane potential analysis using tetramethylrhodamine ethyl ester (TMRE), nuclear morphology by Hoechst staining and confocal microscopy, DNA damage assessment by alkaline comet assay, and enzyme-linked immunosorbent assay (ELISA) for TRAIL protein detection. Additional NSCLC cell lines: Calu-3, H1975 GFP⁺, and H1299 GFP⁺ were used for viability-based bioassays to support mRNA-induced TRAIL activity.The selected polymer formed compact nanoparticles with 100-200 nm size and+15-40 mV zeta-potential. In A549 cells, TRAIL mRNA induced a clear time-dependent apoptotic response: viability declined progressively and reached approximately 40-50% at later time points with higher mRNA doses. Caspase-3/7 activity increased by ~2-fold at 24 hours and remained detectable at 48-72 hours. Confocal imaging showed mitochondrial depolarization together with condensed and fragmented nuclei, and comet assay confirmed DNA strand damage. siRNAs alone reduced viability but did not match the effect of TRAIL mRNA. In combination studies, siRNAs allowed lower TRAIL mRNA doses to achieve viability reductions comparable to higher-dose mRNA alone and maintained reduced viability further into the time course, improving both potency and duration of response.The delivery platform evaluated here supported effective TRAIL mRNA activity in A549 cells, and incorporating siRNAs further reinforced and prolonged the apoptotic response at reduced mRNA doses. These findings highlight a practical path toward combination nucleic acid strategies designed to counter apoptotic resistance in NSCLC.Portions of this abstract were drafted with the assistance of AI under the supervision and full scientific verification of the authors.", "source_company": "University of Alberta", "source_org_type": "大学", "row_number": 915, "target_meta": "TRAIL/TRAIL receptor", "MOA_meta": "其他"}, {"drug_name": "Pleozymes", "company": "University of Houston", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "中", "total_score": 50.5, "institution_score": 35, "track_score": 75, "milestone_score": 45, "field_heat_score": 70, "bonus_score": 4, "brief_reason": "Pleozymes为氧化碳纳米酶，通过多酶活性调节氧化还原和代谢增强CAR-T细胞持久性，机制新颖但靶点未明确披露。大学机构得分较低，preclinical阶段无临床里程碑，但CAR-T代谢优化属热门赛道且有明显细胞水平改善，综合热度和亮点加分使其处于中等重要性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9369", "id": "oFXM_5wBX1NQZOEH-LS6", "source_drug_name": "Pleozymes", "title": "Pleiotropic oxidized carbon nanozymes reprogram CAR T cell metabolism to enhance persistence through redox modulation", "abstract_text": "Adoptive CAR T cell therapy faces major challenges in solid tumors due to chronic antigen stimulation, oxidative stress, and metabolic exhaustion. We recently developed Pleozymes, pleiotropic oxidized carbon nanozymes that function as synthetic redox mediators with multiple enzymatic activities, including superoxide dismutase-like scavenging and NADH/NAD⁺ interconversion. Pleozymes are 3-8 nm oxidized carbon nanoparticles synthesized from coconut-derived activated charcoal and exhibit broad redox potential and mitochondrial localization, enhancing both oxidative phosphorylation and glycolysis in mammalian cells. To investigate their role in T cell metabolic resilience, we treated GPC3-targeted CAR T cells with Pleozymes during chronic co-culture with GPC3-positive HCC Huh7 cells over repeated stimulation cycles. Cell proliferation, apoptosis, exhaustion marker expression, and memory subset differentiation were assessed by flow cytometry and metabolic assays. Pleozymes markedly enhanced CAR T cell expansion and viability across repeated tumor challenges. Apoptotic rates were reduced, and expression of exhaustion markers TIM-3 and LAG-3 decreased significantly. Pleozymes promoted differentiation toward T stem cell memory (TSCM) and central memory (TCM) phenotypes, indicating improved persistence potential. Metabolic profiling indicated elevated total ATP levels and enhanced NAD⁺-dependent catabolic activity, consistent with concurrent activation of glycolysis, fatty acid β-oxidation, and tricarboxylic acid (TCA) cycle flux. Collectively, these findings demonstrate that Pleozymes act as metabolic cofactors that restore redox balance and sustain bioenergetic flexibility in CAR T cells. By mitigating exhaustion and enhancing memory differentiation, Pleozymes offer a novel, non-genetic strategy to improve CAR T cell persistence and antitumor efficacy in solid tumor settings.", "source_company": "University of Houston", "source_org_type": "大学", "row_number": 945, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "CXCR1/2 antagonist", "company": "Fred Hutchinson Cancer Center", "org_type": "研究机构", "target": "CXCR1/2", "modality": "inhibitor", "importance_level": "中", "total_score": 50.5, "institution_score": 35, "track_score": 65, "milestone_score": 55, "field_heat_score": 60, "bonus_score": 2, "brief_reason": "CXCR1/2 antagonist靶向抑制骨转移前列腺癌中IL1Bhi中性粒细胞驱动的免疫治疗耐药机制，具有潜在逆转ICI耐药价值。研究机构背景+preclinical体内外机制验证使整体重要性中等，赛道有一定热度但非最热门靶点/模态。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10480", "id": "jJ7M_5wBZznHJdnt_W3O", "source_drug_name": "CXCR1/2 antagonist", "title": "Dissecting myeloid-driven mechanisms of immunotherapy resistance in prostate cancer bone metastases", "abstract_text": "Background: Patients with metastatic castration-resistant prostate cancer (mCRPC) are generally refractory to immune checkpoint inhibitors (ICIs), particularly those with bone metastases, the most frequent site of disease progression (70-90%). The bone marrow (BM) harbors diverse immune populations, with myeloid cells comprising >70% of its cellular compartment. Among these, neutrophils, known mediators of ICI resistance across multiple malignancies, predominate, whereas macrophages, including SPP1-high tumor-associated macrophages (SPP1hi-TAMs), are relatively sparse, implicating neutrophils as potential key drivers of ICI resistance. However, their role in human mCRPC bone metastases remains poorly characterized. We hypothesize that single-cell characterization of immunosuppressive neutrophil subsets can find new therapeutic opportunities to enhance immunotherapeutic efficacy.\nMethods: We performed single-cell profiling of prostate cancer biopsies across disease stages and tumor sites, including bone metastases, as well as bone samples from tumor-free patients who underwent hip replacement surgery. To validate these findings, we also employed a murine intraosseous CRPC model, combining multi-omic single-cell analyses with functional assays and mechanistic studies.\nResults: Single-cell profiling of patients revealed abundant neutrophil populations in the bone compared to other soft tissues, with distinct subsets corresponding to developmental trajectories. Among mature neutrophils, an inflammatory subset expressing elevated IL1B expression (IL1Bhi-mNeu) was significantly enriched in mCRPC bone metastases versus tumor-free bone tissues and expressed elevated immunosuppressive transcriptional programs. Multi-omic analyses of the intraosseous CRPC murine model identified an analogous Il1bhi-mNeu population that suppressed CD8+ T cell function in co-culture. In vivo studies showed that targeting Il1bhi-mNeu with a CXCR1/2 antagonist or adoptive transfer of these neutrophils into CRPC-bearing mice demonstrated that Il1bhi-mNeu are key drivers of ICI resistance in intraosseous CRPC. Pathway analyses implicated pro-tumor inflammatory signaling as a major mechanism, in particular through IL-1β-mediated pathways. Pharmacologic inhibition of IL-1R diminished Il1bhi-mNeu -mediated CD8+ T cell suppression in vitro and improved ICI responsiveness in vivo.\nConclusions: Our studies identify a distinct mediator of immunotherapy resistance in prostate cancer bone metastases. We demonstrate that mature inflammatory neutrophils (IL1Bhi-mNeu) are enriched in human mCRPC bone metastases and drive ICI resistance through IL-1R signaling. These findings suggest that targeting these cells and their signaling pathways could represent promising therapeutic strategies for overcoming ICI resistance in advanced prostate cancer.", "source_company": "Fred Hutchinson Cancer Center", "source_org_type": "研究机构", "row_number": 1043, "target_meta": "CXCR1,CXCR2", "MOA_meta": "抑制剂"}, {"drug_name": "anti-IL-10", "company": "University of Washington", "org_type": "大学", "target": "IL-10", "modality": "inhibitor", "importance_level": "中", "total_score": 50.5, "institution_score": 35, "track_score": 65, "milestone_score": 55, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "anti-IL-10为IL-10阻断剂，在CRLM肿瘤切片培养中显示可增加凋亡并激活抗肿瘤免疫，靶向肿瘤相关巨噬细胞介导的免疫抑制。大学机构得分较低，但IL-10阻断在肝转移免疫抑制中的机制探索具有一定赛道热度和潜在转化价值。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8098", "id": "mp7M_5wBZznHJdnt_W3O", "source_drug_name": "anti-IL-10", "title": "Heterogeneity in outcomes of cytokine blockade identifies plausible role for SPP1+macrophages in colorectal liver metastasis immune suppression", "abstract_text": "The failure of immunotherapy to demonstrate a benefit in patients with colorectal cancer liver metastases (CRLM) is likely due to both liver-specific immune tolerance and cancer-specific immune evasion mediated by tumor associated macrophages (TAMs), suppressive cytokines (e.g., interleukin-10/IL-10), and immune checkpoints, such as PD-1-PD-L1. We previously demonstrated that IL-10 blockade can activate antitumor immunity in tumor slice cultures (TSC) of CRLM, while PD-1 blockade failed to do so. We hypothesized that immunosuppressive TAMs in the tumor immune microenvironment (TIME) contributed to treatement failure.\nCases were classified as responders or non-responders to IL-10 blockade. Clinical characteristics were analyzed. Bulk and single cell RNA sequencing (RNAseq) and multiplexed immunofluorescence (mIF) were performed on subsets of treated samples. RNAseq data were analyzed in R (Seurat) and Python (Scanpy). AIVIA software was used to quantify SPP1 staining on mIF.\nIL-10 blockade increased apoptosis (29% to 45%, p<0.05) across all TSC (n=59). Using two tailed t-test, cases were classified by percent apoptosis in anti-IL-10 treatment versus control as responders (53% vs 23%, p<0.05) and non-responders (25% vs 24%, p=0.67).\nClinical characteristics including primary site, metachronous/synchronous metastasis, mutation status, and prior therapy were not significantly different between groups. BulkRNAseq demonstrated no difference in baseline IL-10 or IL-10 receptor gene expression between groups. scRNAseq identified TAMs as the major source and both T cells and TAMs as recipients of IL-10 signaling.\nWhile non-responders had higher baseline expression of genes related to CD8+ T cell activation (p=0.03) and cytotoxicity (p=0.03), they also had a higher abundance of M2-macrophage related genes (p=0.02) and CD8+ T cell exhaustion (p=0.04). Further interrogation of immunosuppressive signaling pathways showed that SPP1 (encoding osteopontin/OPN) is largely expressed by TAMs within CRLM, while T cells and TAMs express OPN receptors (CD44, ITGB1). mIF demonstrates colocalization of macrophage markers (CD68/CD163) and OPN/SPP1. Preliminary analysis showed that non-responders had significantly more OPN/SPP1+ cells on baseline mIF (4.3 vs 0.1%, P=0.01).\nImportantly, we determined that OPN secretion is significantly reduced in responders but unchanged in non-responders. The results suggest a role for TAM-related OPN-mediated immunosuppression in the failure of immunomodulatory treatment.\nWe identify SPP1+ TAMs as a potentially critical immunosuppressive population in the TIME of liver metastases. Future work will leverage both orthotopic CRLM models and spatial transcriptomics of human tumors to explore the role of osteopontin signaling in CRLM.", "source_company": "University of Washington", "source_org_type": "大学", "row_number": 1055, "target_meta": "IL-10", "MOA_meta": "抑制剂"}, {"drug_name": "MAIT cell activation and rejuvenation system (MARS)", "company": "University of California, Los Angeles", "org_type": "大学", "target": "MR1 (通过5-OP-RU激动MAIT细胞)", "modality": "other", "importance_level": "中", "total_score": 50.5, "institution_score": 35, "track_score": 75, "milestone_score": 45, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "MARS为肝靶向生物仿生支架递送MAIT激动剂5-OP-RU和IL-15，激活并重振肝癌中耗竭的MAIT细胞发挥抗肿瘤作用。大学背景得分较低，但MAIT细胞免疫治疗+肝癌局部递送具有创新性与较高赛道热度，整体处于中等重要性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5583", "id": "057M_5wBZznHJdnt_W3O", "source_drug_name": "MAIT cell activation and rejuvenation system (MARS)", "title": "An in vivo MAIT cell activation and rejuvenation systemfor liver cancer therapy", "abstract_text": "Mucosal-associated invariant T (MAIT) cells are liver-enriched unconventional T cells with potent antitumor potential, yet in liver cancer they are numerically reduced and functionally exhausted, limiting their therapeutic efficacy. To overcome these limitations, we developed a MAIT cell activation and rejuvenation system (MARS), a biomimetic scaffold engineered to deliver MAIT agonist 5-OP-RU and IL-15 directly to the liver, promoting MAIT cell activation, rejuvenation, and cytotoxic function. Ex vivo, MARS significantly stimulated MAIT cells from liver cancer patient peripheral blood and liver tissues, enhancing their effector function and cytotoxicity while reducing exhaustion. In vivo, MARS efficiently localized to the liver, boosting MAIT cell activation, expansion, and tumor-killing capacity in human liver cancer xenograft mouse models. Importantly, in a human myeloid cell-engrafted mouse model, MARS facilitated the depletion of liver MR1+ tumor-associated macrophages, further supporting MAIT cell antitumor activity. Collectively, through its biomimetic design and liver-targeted immunomodulatory effects, MARS provides an efficient and safe strategy to enhance MAIT cell-based immunotherapy for liver cancer.", "source_company": "University of California, Los Angeles", "source_org_type": "大学", "row_number": 1102, "target_meta": "MR1", "MOA_meta": "其他"}, {"drug_name": "CD19 CAR-T", "company": "Shanghai Children’s Medical Center, Shanghai Jiao Tong University", "org_type": "医院", "target": "CD19", "modality": "CAR", "importance_level": "中", "total_score": 50.5, "institution_score": 35, "track_score": 85, "milestone_score": 40, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "CD19 CAR-T为成熟的CAR-T疗法，靶向CD19在B-ALL中已广泛应用，但本摘要聚焦于治疗后罕见myeloid lineage switch的机制研究，而非药物开发本身。机构为医院/大学，赛道仍具热度，但缺乏新药里程碑进展导致综合重要性中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9806", "id": "K57M_5wBZznHJdnt_W7O", "source_drug_name": "CD19 CAR-T", "title": "Single-cell multi-omics reveals co-mutation of TP53 and epigenetic gene driving myeloid transformation in B-ALL following CAR-T therapy", "abstract_text": "Lineage switch is a rare phenomenon, occurring in less than 1% of leukemia cases. However, with the advent of CD19-targeted immunotherapies such as CAR-T and blinatumomab, it has emerged as a significant complication. Identifying patients at high risk for lineage switch prior to immunotherapy is critical, yet predictive biomarkers remain unclear. In a cohort of 65 B-ALL patients who relapsed after CAR-T therapy, we identified one case of myeloid lineage switch with unknown mechanism. Transcriptomic sequencing across three timepoints: pre-CAR-T, first CAR-T relapse, and second CAR-T relapse (myeloid switch) confirmed a consistent driver gene profile (ETV6::RUNX1 fusion, NF1, WNK1 and CIC mutations), ruling out a secondary malignancy. To elucidate the mechanism, we performed single-cell DNA-protein sequencing (Mission Bio Tapestri platform) and single-cell RNA sequencing (10x Genomics platform). At first CAR-T relapse, we identified five distinct clones. After CAR-T therapy, three clones were undetectable, whereas two clones persisted and underwent rapid expansion, concomitant with myeloid lineage switch. Notably, both of these clones harboring mutations in TP53 and epigenetic regulator STAG2. We further discovered a distinct population of lineage-infidelity cells (CD117+CD71+ CD34+CD38+CD56+CD19dim) that co-express myeloid and B-lineage markers, representing a heightened plasticity that may facilitate CAR-T evasion. Projection of our scRNA-seq data onto a normal developmental atlas showed pre-CAR-T sample from the lineage-switch case encompassed a broad spectrum, whereas control case of CD19-negative relapse due to CD19 mutation were confined to the pro-B/pre-B stages. Based on these findings, we hypothesized that co-mutation of TP53 and epigenetic regulators predisposes cells to lineage switch. To validate this finding, we performed a longitudinal flow cytometry analysis. Patients were stratified into two groups: a co-mutation group (n=4) harboring TP53 and epigenetic gene mutations, and a control group (n=2) lacking these mutations. The co-mutation group exhibited significant downregulation of the B-lineage marker CD19 and concurrent upregulation of the myeloid marker following CAR-T treatment. In contrast, the control group showed no notable changes. In conclusion, our data suggests that co-mutations in TP53 and epigenetic genes enhance plasticity in B-ALL. Under the selective pressure of CD19 CAR-T therapy, subclones harboring these mutations are preferentially expanded, leading to lineage switch. We propose monitoring myeloid marker expressing subclones in B-ALL patients carrying co-mutations in TP53 and epigenetic genes during immunotherapy is important to improve their prognosis.", "source_company": "Shanghai Children’s Medical Center, Shanghai Jiao Tong University", "source_org_type": "医院", "row_number": 1154, "target_meta": "CD19", "MOA_meta": "其他"}, {"drug_name": "anti-PD1", "company": "Peking University Cancer Hospital & Institute", "org_type": "医院", "target": "未披露", "modality": "inhibitor", "importance_level": "中", "total_score": 50.5, "institution_score": 35, "track_score": 75, "milestone_score": 45, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "摘要聚焦anti-PD1联合PD-L2-EV机制增强Th1/Th2平衡及抗肿瘤免疫，但未披露新型抗PD1药物本身靶点/结构信息，仅为机制研究。机构为医院而非药企导致institution_score较低，机制新颖性及PD1赛道热度提供部分加分。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10920", "id": "SZ7M_5wBZznHJdnt_W7P", "source_drug_name": "anti-PD1", "title": "PD-L2-RGMb interaction modulates anti-cancer immunity through swinging the shift of Th1/Th2 cell balance", "abstract_text": "Immune checkpoint blockade has revolutionized gastric cancer (GC) treatment, yet primary and acquired resistance remain major clinical challenges. Here, we identified extracellular vesicles (EVs) expressing programmed death-ligand 2 (PD-L2-EVs) as a key determinant of anti-PD1 response in GC. Through profiling the extracellular vesicle protein expression profiles in plasma samples from a retrospective cohort of 76 patients, we demonstrated that high baseline PD-L2-EV levels correlate with improved immunotherapy response and survival. Using multiple immunocompetent murine models, we showed that PD-L2-EVs synergize with anti-PD1 to suppress tumor growth by remodeling the tumor immune microenvironment, enhancing CD8+ T cell and NK cell infiltration while reducing immunosuppressive cell populations. Mechanistically, PD-L2 possesses differential binding dynamics between PD1 and repulsive guidance molecule b (RGMb), its binding to the latter mediates Th1 differentiation through promoting STAT4-signaling and augments CD8+ T cell’s anti-tumor immunity. On the other hand, AFP reduces cancer cell’s expression of PD-L2 and impaired Th1 differentiation, which explained the resistance to immunotherapy for the subtype of AFP-GC. Importantly, through shifting T helper 1/2 cells’ balance towards Th1 under PD1 blockade, PD-L2-EV enhances the efficacy of anti-PD1 but not for anti-PD-L1 therapy. Our work nominated PD-L2-EVs as a predictive biomarker in guiding the selection of different types of immunotherapy and potentiates engineered PD-L2-EV as a candidate for therapeutic combination, particularly in AFP-positive patients.", "source_company": "Peking University Cancer Hospital & Institute", "source_org_type": "医院", "row_number": 1176, "target_meta": "not available", "MOA_meta": "抑制剂"}, {"drug_name": "P-12", "company": "Stanford University", "org_type": "大学", "target": "PD-L1", "modality": "other", "importance_level": "中", "total_score": 50.5, "institution_score": 35, "track_score": 75, "milestone_score": 45, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "P-12为PD-L1阻断小肽，通过LRP1靶向的聚合物纳米偶联物实现BBB穿透递送，针对黑色素瘤脑转移。大学机构分数较低，但PD-L1+脑递送+纳米平台在免疫治疗耐药领域有一定赛道热度和临床转化潜力。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6384", "id": "fp7M_5wBZznHJdnt_W7P", "source_drug_name": "P-12", "title": "Targeted polymeric nanoconjugates for BBB penetration and time specific delivery of PDL1 blocking small peptides via LRP1 targeting in melanoma brain metastases", "abstract_text": "Background: Melanoma brain metastases (MBM) show high CNS tropism with limited benefit from single-agent ICB; a combination regimen with an AXL inhibitor may improve responses but carry substantial toxicity. The brain TiME features scarce T cells, abundant TAMs, and glial PD-L1, promoting immune evasion and poor ICB efficacy. BBB penetrant strategies via peptide-based Immuno-Nano-Conjugates (INCs) are under development, though intrathecal delivery has not improved survival. LRP-1-mediated INCs delivery may enable BBB transport and TAM-TiME reprogramming. Here, we report a targeted nanoplatform that crosses the BBB and delivers PD-L1-blocking peptides to the TiME.\nMethods: Immuno-Nano-Conjugates (INCs) were synthesized by conjugating a biocompatible malic acid polymer conjugated with (i) P-12, a PD-L1 blocking peptide, and (ii) Angiopep-2 (AP2), a ligand for LRP-1 mediated transcytosis. Therapeutic efficacy, safety, toxicity, and biodistribution studies were assessed using an in vitro static BBB-on-a-chip brain tumor model and in vivo in established murine cancer models. Clinical transcriptomic correlation data from metastatic melanoma (TCGA-SKCM, n = 471) were analyzed via the GDC legacy archive to construct Kaplan-Meier survival curves.\nResults: The INCs traversed the BBB and demonstrated penetration in a BBB-on-a-chip brain tumor model. Upon delivery, INCs were selectively internalized by the activated TiME environment, thereby promoting antitumor immune cell activation and proliferation. In vivo efficacy, safety, toxicity, and biodistribution revealed superior brain accumulation of INCs relative to ICB agents and significant efficacy and a better safety profile. Clinically, high AXL expression correlated with nonresponse to ICB in Stage IV melanoma and aligned with immunosuppressive myeloid signatures, demonstrating an association with reduced survival in patients with brain metastases. In subcutaneous melanoma models, the combination of P-12 (anti-PD-L1)- based peptides with the AXL inhibitor Bemcentinib yielded greater tumor burden reduction than anti-PD-1 monotherapy, suggesting the potential to circumvent ICB resistance in MBM settings.\nConclusion: Our data indicate that BBB transcytosis of INCs via LRP-1 mediates enhanced delivery of PD-L1 blocking peptides to the TiME, supporting improved therapeutic exposure for MBM. AXL emerges as a critical therapeutic target and a rational axis for combination strategies with targeted nanoplatforms to treat resistant MBM. Ongoing studies across additional MBM-relevant models aim to validate these findings and further optimize second-generation bispecific INCs approaches.", "source_company": "Stanford University", "source_org_type": "大学", "row_number": 1209, "target_meta": "PDL1", "MOA_meta": "其他"}, {"drug_name": "AMG44", "company": "H. Lee Moffitt Cancer Center & Research Institute", "org_type": "医院研究机构", "target": "PERK", "modality": "inhibitor", "importance_level": "中", "total_score": 50.5, "institution_score": 35, "track_score": 65, "milestone_score": 55, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "AMG44为高选择性PERK抑制剂（小分子口服抑制剂），靶向UPR通路中介PERK，在ccRCC细胞中联合ER应激剂或VEGF抑制剂显示协同降低细胞活力。机构为医院/研究机构非商业药企、仍处工具化合物/前临床研究阶段无临床进展，导致总分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/2415", "id": "RlXM_5wBX1NQZOEH-LS6", "source_drug_name": "AMG44", "title": "Evaluating the unfolded protein response as a therapeutic target in clear cell renal cell carcinoma patients", "abstract_text": "Metastatic clear cell renal cell carcinoma (ccRCC) is an incurable and lethal disease. While treatment of ccRCC has shifted toward antiangiogenic and immunotherapy combinations, long-term response is rare, underscoring the urgent need for novel therapeutic targets. We previously demonstrated in a murine model that therapeutic targeting of the unfolded protein response (UPR) via the mediator PKR-like ER kinase (PERK) can reverse tumor progression, immune suppression, and resistance to immune checkpoint blockade (ICB) (Mandula et al. Cancer Cell. 2022). Early-phase clinical studies are now evaluating PERK inhibition as a therapeutic strategy in solid tumors, including ccRCC. Here, we performed a retrospective analysis of patients with ccRCC using an analytical framework to estimate PERK activity from transcriptome data. We evaluated three independent ccRCC patient data sets - iATLAS patients treated with ICB (n = 296), ORIEN AVATAR patients treated with ICB (n = 85), and a TCGA treatment-naive cohort (n = 534). Across these datasets, PERK expression was associated with increased progression risk and worse overall survival. To evaluate the role of PERK in the context of endoplasmic reticulum (ER) stress, we generated a PERK knockout model using CRISPR gRNA in ccRCC cell lines and then challenged the cells with an ER stressor, thapsigargin. Interestingly, we found cytoplasmic vacuolization reminiscent of an unresolved unfolded protein response, ER swelling, and proteostasis disruption. Moreover, joint treatment with the PERK inhibitor AMG44 and thapsigargin significantly reduced viability in ccRCC cells. To further assess the therapeutic potential of PERK inhibition during standard-of-care therapy, we evaluated its impact during VEGF blockade. We observed decreased cell viability in PERK-silenced cells following cabozantinib (VEGF inhibitor) exposure, either through drug inhibition or genetic deletion. In summary, as clinical interest in PERK inhibition (PERKi) grows across multiple solid tumors, our findings highlight PERK as a potential therapeutic target in ccRCC and identify associated biomarkers that may inform future clinical strategies.", "source_company": "Moffitt Cancer Center\nH. Lee Moffitt Cancer Center & Research Institute", "source_org_type": "医院\n研究机构", "row_number": 1276, "target_meta": "EIF2AK3", "MOA_meta": "抑制剂"}, {"drug_name": "histone deacetylase inhibitors", "company": "Harvard Medical School", "org_type": "大学", "target": "HDAC", "modality": "inhibitor", "importance_level": "中", "total_score": 50, "institution_score": 35, "track_score": 65, "milestone_score": 55, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "药品为HDAC抑制剂，在TNBC模型中针对化疗+免疫治疗后出现的间质化免疫抑制耐药克隆显示选择性疗效，并与免疫治疗联合在老年小鼠中实现无化疗的显著抗瘤效果。机构为大学得较低分，赛道为成熟靶点但表观遗传耐药机制有一定新意，preclinical阶段但显示清晰的年龄适应治疗潜力。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/2709", "id": "A1XM_5wBX1NQZOEH-LK6", "source_drug_name": "histone deacetylase inhibitors", "title": "Overcoming age-related immune dysfunction and chemoresistance in breast cancer", "abstract_text": "Age is a major determinant of breast cancer incidence and outcome, with both the youngest and oldest patients experiencing worse survival, regardless of subtype or stage. However, the mechanisms by which aging shapes tumor biology and therapeutic response remain incompletely understood. Our team has been investigating age-associated differences in breast tumor cell states, tumor microenvironment (TME) composition, and treatment vulnerabilities. Using analyses of bulk and single-cell transcriptomic datasets, we developed an age specific program enrichment (ASPEN) pipeline to identify transcriptional programs associated with patient age. Across over 1500 tumors, we observed subtype-specific age-related changes in both cancer cells and the TME. In triple-negative breast cancer (TNBC), aging was associated with increased epithelial-mesenchymal transition (EMT) in cancer cells and inflammatory responses in the TME, particularly in cancer-associated fibroblasts. In estrogen receptor-positive (ER+) breast cancer, tumors from older patients displayed elevated estrogen receptor 1 expression and reduced metabolic activity in immune and vascular cells. Cell-cell interactome analysis identified candidate signaling pathways that may drive these age-associated cellular states, and tissue-based spatial analyses across independent clinical cohorts supported the computational findings. To investigate functional consequences of age-related tumor states in TNBC, we used a mouse model reflecting aggressive disease typical of younger patients. Nevertheless, young mice derived greater benefit from standard chemotherapy plus immunotherapy than aged mice. Both aging and paclitaxel treatment independently selected for the emergence of a chemoresistant, mesenchymal-like (i.e., EMT), immunosuppressive tumor subclone, with analogous biomarkers observed in tumors from older TNBC patients. Screening FDA-approved compounds identified histone deacetylase inhibitors (HDACi) as selectively effective against these clones, revealing an epigenetic vulnerability of the mesenchymal, immunosuppressive tumor state. In aged mice, HDACi combined with immunotherapy elicited robust anti-tumor responses and extended survival without chemotherapy whereas young mice achieved optimal disease control when chemotherapy was included with HDACi and immunotherapy. These results suggest a path toward chemotherapy-sparing strategies for older patients who often cannot tolerate cytotoxic regimens. Although pan-HDAC inhibitors have known toxicity limitations, these findings provide proof-of-principle that targeting this epigenetic program may offer an avenue for developing less toxic, age-adapted therapies.\nTogether, these findings reveal that age shapes breast cancer cell states, tumor-TME interactions, and therapeutic vulnerabilities. Our results highlight the emergence of age-associated resistant tumor programs and demonstrate that optimal treatment strategies may differ between younger and older patients. These studies provide a framework for developing safer, more effective age-adapted therapeutic approaches to improve outcomes across lifespan.", "source_company": "Harvard Medical School", "source_org_type": "大学", "row_number": 492, "target_meta": "HDAC", "MOA_meta": "抑制剂"}, {"drug_name": "polyIC-LNP", "company": "Institute of Cancer Research, Shenzhen Bay Laboratory", "org_type": "研究机构", "target": "未披露", "modality": "other", "importance_level": "中", "total_score": 50, "institution_score": 35, "track_score": 65, "milestone_score": 55, "field_heat_score": 60, "bonus_score": 2, "brief_reason": "polyIC-LNP为肝靶向脂质纳米粒包裹的polyIC（合成dsRNA），通过诱导PD-L1表达实现与anti-PD-L1协同免疫治疗肝癌，机制新颖但靶点未明确。机构为研究机构而非药企导致机构分较低，赛道免疫+递送系统有一定热度，动物模型显示单药有效但仍处早期研究阶段。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10544", "id": "UlXM_5wBX1NQZOEH-LO6", "source_drug_name": "polyIC-LNP", "title": "New thought and strategy of liver cancer immunotherapy", "abstract_text": "This study is to explore new strategy of liver cancer immunotherapy. Despite the great success of immunotherapy in a broad range of cancers, the vast majority of cancer patients showed poor response. Approximately 17% liver cancer patients responded to monotherapy of pembrolizumab and 20% responded to nivolumab. A combination of nivolumab and ipilimumab increased the response rate to 30% in HCC. Simultaneous blockade of PD-L1 and VEGF signaling using atezolizumab and bevacizumab achieved better overall and progression-free survival than sorafenib in HCC.\nOur previous data showed that monotherapy with anti-PD-L1 antibody exhibited no inhibitory effect in primary liver cancer driven by classical oncogenes in mice. Given a robust induction of PD-L1 expression by polyIC in the liver, we reasoned that the synthetic dsRNA could sensitize hepatic response to αPD-L1 treatment. Indeed, combined treatment of polyIC and anti-PD-L1 showed markedly improved efficacy in mouse HCC models.\nA combinatorial therapy of polyIC and anti-PD-L1 exhibited an intriguing synergistic effect in liver tumors. We interrogated the compositions and changes of immune cell subtypes infiltrated into the tumors grown subcutaneously or in the liver, as well as the whole liver of tumor-bearing mice. The data suggest that it is the tumor microenvironment, rather than the tumor cells, that determine the response to immunotherapy.\nWe have also found that the polyIC+antiPD-L1 combination exhibited more potent anti-tumor effect than antiPD-L1+antiVEGFA. Further, we demonstrate that a monotherapy of liver-targeting lipid nanoparticles that encapsulate polyIC (polyIC-LNP) is sufficient to suppress both primary and metastasized liver tumor progression in mouse models.\nCurrent working address: Institute of Cancer Research, Shenzhen Bay Laboratory", "source_company": "UC San Diego School of Medicine", "source_org_type": "大学", "row_number": 708, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "S1PR3 inhibitor", "company": "Huazhong University of Science and Technology", "org_type": "大学", "target": "S1PR3", "modality": "inhibitor", "importance_level": "中", "total_score": 50, "institution_score": 35, "track_score": 65, "milestone_score": 55, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "S1PR3抑制剂通过阻断S1P-S1PR3-ERK-AKT通路抑制食管癌CAF激活和肿瘤生长，机制新颖但仅为学术体内药效验证。机构为大学非药企、仍处早期研究阶段导致综合评分中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8484", "id": "aFXM_5wBX1NQZOEH-LO6", "source_drug_name": "S1PR3 inhibitor", "title": "Cigarette smoke-induced sphingosine-1-phosphate drives cancer-associated fibroblasts activation and esophageal cancer carcinogenesis", "abstract_text": "The metabolic impact of cigarette smoke on tumor microenvironment remodeling remains poorly defined. Here, we identify a missense variant in ACER1 that confers elevated risk of esophageal squamous cell carcinoma (ESCC) specifically among smokers, based on a gene-smoking interaction analysis involving 10,716 cases and 12,637 controls. Functional assays demonstrate that the risk allele synergizes with nicotine and benzo[a]pyrene to enhance sphingosine-1-phosphate (S1P) biosynthesis and secretion in ESCC epithelial cells. Integrated single-cell RNA sequencing, spatial proteomics, and multiplex immunofluorescence analyses across multi-stage ESCC samples reveal that this ACER1-driven sphingolipid reprogramming promotes the activation of myofibroblastic cancer-associated fibroblasts (myCAFs). Mechanistically, epithelial-secreted S1P engages the S1PR3-ERK-AKT signaling cascade in fibroblasts, promoting a pro-tumorigenic stromal state. Pharmacological inhibition of S1PR3 markedly suppresses ESCC growth in vivo. These findings uncover a critical gene-environment interaction driving pro-tumorigenic microenvironmental remodeling in esophageal tumorigenesis and highlight a metabolic vulnerability for early detection and therapeutic intervention.", "source_company": "Huazhong University of Science and Technology", "source_org_type": "大学", "row_number": 720, "target_meta": "S1PR3", "MOA_meta": "抑制剂"}, {"drug_name": "PR8 deltaNS1", "company": "Icahn School of Medicine at Mount Sinai", "org_type": "大学", "target": "未披露", "modality": "oncolytic virus", "importance_level": "中", "total_score": 50, "institution_score": 35, "track_score": 75, "milestone_score": 45, "field_heat_score": 65, "bonus_score": 3, "brief_reason": "PR8 deltaNS1为减毒型溶瘤流感病毒（oncolytic IAV），靶点未明确披露。大学机构基础分较低，但溶瘤病毒赛道热度较高且preclinical模型显示跨亚型免疫增强疗效及记忆免疫，综合潜力中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3640", "id": "p1XM_5wBX1NQZOEH-LO6", "source_drug_name": "PR8 deltaNS1", "title": "Pre-existing immunity boosts therapeutic efficacy of oncolytic influenza a virus in the presence and absence of neutralizing antibodies", "abstract_text": "The study of oncolytic viruses that naturally target humans requires models that elucidate the impact of pre-existing immunity on therapeutic efficacy. Recent studies have shown that the presence of anti-viral T cells in the tumor can be associated with potentiation of oncolytic viruses [1,2]. Conversely, the presence of neutralizing antibodies has also been shown to abolish response [1]. Thus, we hypothesized that pre-existing immunity to Influenza A virus (IAV) would lead to abrogation of oncolytic IAV therapy. To study the effect of neutralizing antibodies and IAV-specific T cells on oncolytic virus treatment, we established models of both homosubtypic and heterosubtypic immunity. Mice were infected with either PR8 virus (H1N1) or X-31 virus (H3N2.) 6 weeks post infection, mice were given bilateral CT26 tumors, and one tumor was treated with PR8 deltaNS1. Both tumors were monitored for tumor growth and overall survival. In a single tumor model, flow cytometry was used to define changes in the immune landscape unique to immunized mice. Additionally, anti-viral TILs were analyzed and characterized. Interestingly treated tumors displayed significant delays in tumor growth in PR8 and X-31 mice compared to naïve mice. Additionally, an increased abscopal effect in the contralateral tumor was only observed in X-31 mice. Treatment of X-31 mice resulted in a 20% increase in overall survival compared to PR8 and naïve mice. Rechallenged mice rejected tumor engraftment, indicating a durable anti-tumor memory response.There was an increase in both tumor infiltrating CD8+ and CD4+ T cells in the single tumor model. Amongst CD4s, there was a significant decrease in the presence of T regulatory cells (Treg); corresponding with an increase in CD8:Treg ratio. Immunized tumor bearing mice showed infiltration of anti-viral CD8s prior to treatment with oncolytic virus. X-31 mice had a higher prevalence of anti-IAV CD8s in the tumor and draining lymph node. In both immunization models, CD44+ anti-IAV CD8s were CD127hiCD69hi indicating a central memory phenotype. Further phenotyping TILs in X31-immunized, tumor bearing mice displayed a trends to less T-cell exhaustion and increased cytotoxicity. In models of both homosubtypic and heterosubtypic immunity, therapeutic efficacy is strengthened. This indicates that the presence of neutralizing antibodies does not hinder the therapeutic efficacy of the virus and that the presence of anti-IAV T cells in both models may be responsible for this potentiation. Future studies aim to understand how anti-viral T cells in the TME contribute to anti-tumor response via interaction with anti-tumor T cells and overall myeloid cells.", "source_company": "Icahn School of Medicine at Mount Sinai", "source_org_type": "大学", "row_number": 762, "target_meta": "not available", "MOA_meta": "溶瘤病毒"}, {"drug_name": "dominant negative protein", "company": "University of Miami Miller School of Medicine", "org_type": "大学", "target": "soluble TNF (sTNF)", "modality": "dominant negative protein", "importance_level": "中", "total_score": 50, "institution_score": 35, "track_score": 65, "milestone_score": 55, "field_heat_score": 60, "bonus_score": 2, "brief_reason": "药物为dominant negative protein靶向sTNF以阻断可溶性TNF，增强HER2+乳腺癌中TKI（lapatinib/tucatinib）的疗效并抑制转移。大学机构分数较低，但sTNF阻断+TKI组合在耐药模型中显示较强协同和转移抑制，preclinical数据清晰，赛道有一定创新性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8918", "id": "qlXM_5wBX1NQZOEH-LO6", "source_drug_name": "dominant negative protein", "title": "Soluble TNF blockade as a strategy to enhance tyrosine-kinase inhibitor response and control metastatic burden in HER2-positive breast cancer", "abstract_text": "Tyrosine kinase inhibitors (TKIs), such as lapatinib and tucatinib, are used to treat metastatic HER2-positive breast cancer, especially those located in the brain, as they can cross the blood-brain barrier. Although both TKIs improve survival, there is still an urge to boost their efficacy and overcome resistance. We have demonstrated that soluble TNF (sTNF) blockade overcomes resistance to trastuzumab-based therapies targeting HER2 by downregulating mucin 4 (MUC4), which shields its epitope on the HER2 molecule. Now, we asked whether sTNF neutralization might overcome TKI-based therapy resistance or enhance its antitumor activity.We used the HER2+/MUC4+ JIMT-1 and its brain-tropic subline JIMT-1BR3-luc cell lines, resistant to lapatinib. For proliferation and cell migration assays, cells were treated with 1 µM lapatinib or 10 µM tucatinib, either alone or combined with 10 µg/ml of a dominant negative (DN) protein that neutralizes sTNF. For preclinical studies, female nude mice bearing JIMT-1 tumors received vehicle, 100 mg/kg lapatinib via oral gavage daily, 10 mg/kg DN i.p. twice a week, or the combination (n=5/group). For JIMT-1BR3-luc tumors, mice were treated with vehicle, 100 mg/kg tucatinib via oral gavage daily, DN twice weekly, or both (n=9/group). Tumor volume was measured biweekly for 21 days; metastases were detected ex vivo by IVIS luminescence.Neither lapatinib nor DN alone impacted JIMT-1 cell proliferation, but their combination reduced cell proliferation by 60%. For JIMT-1Br-luc cells, DN and tucatinib decreased cell proliferation by 35 % and 55%, respectively, and the combination enhanced the effect to 80%. Cell migration was significantly inhibited in both cell lines by their respective combo treatment, compared to the monotherapies.In preclinical studies, treatment with DN, lapatinib, or tucatinib did not affect the primary tumor growth, compared to the vehicle. However, the combination of DN and lapatinib reduced JIMT-1 tumor growth by 77% and, in the case of JIMT-Br-luc tumors, treatment with DN and tucatinib inhibited tumor growth by 68%, compared to the monotherapies. The percentage of JIMT-Br-luc tumor-bearing mice with lung metastases was 100% in the vehicle group, 75% in the DN group, 37.5% in the tucatinib group, and 12.5% in the combined group. Animals with brain and liver metastases accounted for 50% and 75% respectively, in the vehicle group, and were 90-100% reversed upon treatment with either tucatinib or DN, or the combination.These findings highlight that sTNF blockade can overcome lapatinib resistance and improve tucatinib inhibitory effect on cell proliferation, both in vitro and in vivo. In addition, DN was able to curb brain and liver metastasis and lung metastases in combination with tucatinib, underscoring the potential benefit of its use in combination with TKIs in advanced HER2-positive breast cancer patients.", "source_company": "University of Miami Miller School of Medicine", "source_org_type": "大学", "row_number": 764, "target_meta": "TNF-α", "MOA_meta": "其他"}, {"drug_name": "anti-PD-1", "company": "Herbert Irving Comprehensive Cancer Center", "org_type": "医院", "target": "PD-1", "modality": "inhibitor", "importance_level": "低", "total_score": 49.5, "institution_score": 35, "track_score": 75, "milestone_score": 45, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "anti-PD-1为经典PD-1抑制剂，但本摘要仅描述其在胃癌神经-免疫抑制回路中的背景作用，未披露新药或新机制。医院机构+基础机制研究阶段导致总体分较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10826", "id": "E1XM_5wBX1NQZOEH-LG5", "source_drug_name": "anti-PD-1", "title": "Electrical activity powered neural circuit sustains systemic immune evasion in gastric cancer", "abstract_text": "Background: Nociceptive sensory nerves are emerging as active regulators of tumor progression and immune suppression within the tumor microenvironment (TME). We previously showed that gastric cancer cells establish a bi-directional electrical circuit with CGRP⁺ sensory neurons, in which cancer depolarization triggers neuronal firing and CGRP release. Given that sensory afferents serve as the afferent limb of the inflammatory reflex transmitting peripheral signals to the brainstem, we hypothesized that cancer may similarly exploit neural circuits and neuropeptide signaling to regulate systemic immunity.\nMethods: A chemogenetic receptor (PSAM4-5HT₃) was introduced into a syngeneic murine (ACKP) gastric cancer cell line to evoke cancer depolarization in vivo. Cancer-activated neuronal projections were mapped in TRAP2 (Fos-CreERT2) mice using Cre-dependent AAV reporters. Immune profiling was performed to characterize antigen-experienced T cells in the tumor-draining lymph node (TDLN) and various CD8⁺ T-cell subsets within the TME. In vivo imaging was used to monitor T-cell motility dynamics, and GCaMP6s was expressed in immune cells to visualize neuron-triggered calcium flux.\nResults: Cancer depolarization activated nociceptive sensory neurons, which established synapse-like contacts with CD8⁺ TILs preferentially at the perivascular niche and tertiary lymphoid structures. The cancer-coupled sensory nerves upregulated Cxcl10, attracting T cells toward their terminals to form these connections. In a 3-D co-culture system comprising cancer spheroids, dorsal root ganglia, and CD8⁺ TILs, optogenetic stimulation of cancer cells induced a calcium flux in sensory nerve-connected T cells, confirming functional transmission. Local activation of this cancer-nerve-T-cell circuit enhanced T-cell migration toward nerve terminals but diminished effector capacity, evidenced by reduced TNFα and IFNγ expression and limited infiltration into the tumor core. Sensory afferents relayed signals to higher brainstem areas, including the nucleus tractus solitarius (NTS) and rostral ventrolateral medulla (RVLM), eliciting sympathetic output to the TDLN. This afferent-brain-efferent loop retained and immobilized antigen-experienced CD44⁺PD-1⁺ T cells within the TDLN, thereby restraining systemic immunity in a norepinephrine-Adrb2-dependent manner. Anti-PD-1 therapy paradoxically strengthens the cancer-sensory nerve coupling. Ablatio of this cancer-evoked neural circuit restored T-cell effector function systemically and synergized with anti-PD-1 therapy.\nConclusions: These findings reveal that cancer depolarization activates CGRP⁺ sensory neurons to form synaptic contacts with CD8⁺ T cells, linking local peptidergic signaling to systemic immune suppression via the NTS-RVLM-TDLN axis. Disrupting this circuit restores T-cell function and enhances anti-PD-1 response.", "source_company": "Herbert Irving Comprehensive Cancer Center", "source_org_type": "医院", "row_number": 6, "target_meta": "PD1", "MOA_meta": "抑制剂"}, {"drug_name": "anti-PD-1 therapy", "company": "Georgetown Lombardi Comprehensive Cancer Center", "org_type": "医院", "target": "PD-1", "modality": "inhibitor", "importance_level": "低", "total_score": 49.5, "institution_score": 35, "track_score": 75, "milestone_score": 40, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "anti-PD-1 therapy靶向PD-1，属于成熟免疫检查点抑制剂赛道热度较高，但机构为医院/学术中心而非biotech/pharma公司。摘要聚焦TAM亚群与anti-PD-1响应机制研究，属基础与机制探索，无药物自身开发里程碑，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8140", "id": "H1XM_5wBX1NQZOEH-LK6", "source_drug_name": "anti-PD-1 therapy", "title": "A new classification of tumor-associated macrophages and their roles in resistance to immune checkpoint therapy", "abstract_text": "Tumor-associated macrophages (TAMs) perform a wide range of functions in the tumor microenvironment (TME), several of which contribute to resistance to immune checkpoint therapy. Given their high abundance and diverse functions, altering TAM activity is a promising supplement to immune checkpoint therapy. We demonstrate the potential of a new classification of TAMs, characterized by functional distinctions in gene expression, cell-cell interactions, and spatial localization. We validate the functions suggested by gene expression using ex vivo functional assays with primary TAMs. We compare markers of the eight functional TAM subpopulations in murine melanoma data with those in human data to develop a translatable gene signature for each functional subtype. We demonstrate that treating bone marrow-derived macrophages with different cytokine combinations can replicate TAM subtypes in vitro, advancing the field beyond the conventional M1-M2 model and enabling a more comprehensive approach. To demonstrate the importance of TAM subpopulations in response to immune checkpoint therapy, we show differences in the abundance of each subtype in untreated murine tumor models that are responsive or non-responsive to anti-PD-1 therapy. At the single-cell RNA-seq level, we find changes in the TAM landscape of murine SM1 melanoma tumors after systemic treatment with epigenetic-modifying agents, with or without anti-PD-1 therapy, and compare these changes with those observed in publicly available human melanoma data. Anti-PD-1 therapy in murine tumors results in a clear enrichment of APC-TAMs (an antigen-presenting, phagocytic, and complement-driven subpopulation), which is further enhanced by systemic HDAC inhibitors. The IFN-TAMs, which reflect a more conventional “M1” macrophage, are less strongly associated with response to immune checkpoint therapy. We see a reduction in angiogenic, hypoxia-driven “AFH-TAMs” in response to multiple anti-cancer therapies. In future studies, we will harness the APC-TAM population to overcome resistance to immune checkpoint therapy in multiple murine tumor types. Compared with melanoma tumors, murine breast cancers have a significantly higher proportion of ECM-TAMs, macrophages involved in extracellular matrix remodeling and homeostasis. We will aim to pharmacologically alter the abundance of other tumor-supporting macrophage populations, depending on the characteristics of different tumor types.", "source_company": "Georgetown Lombardi Comprehensive Cancer Center", "source_org_type": "医院", "row_number": 25, "target_meta": "PD1", "MOA_meta": "抑制剂"}, {"drug_name": "FAPI", "company": "Cancer Hospital Chinese Academy of Medical Sciences", "org_type": "医院", "target": "未披露", "modality": "RLT imaging agent", "importance_level": "低", "total_score": 49.5, "institution_score": 45, "track_score": 75, "milestone_score": 30, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "FAPI为成像剂，主要靶向FAP（成纤维细胞激活蛋白），用于髓样甲状腺癌的精确手术引导成像，但摘要被禁运未披露具体靶点和机制细节。机构为国内顶级肿瘤医院但非企业，开发阶段为临床前/早期应用无明确里程碑，赛道为放射性配体成像热度较高但总分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/12115", "id": "XFXM_5wBX1NQZOEH-LK6", "source_drug_name": "FAPI", "title": "Covalent FAPI imaging-guided precision surgery in medullary thyroid carcinoma", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Cancer Hospital Chinese Academy of Medical Sciences", "source_org_type": "医院", "row_number": 35, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "anti-PD-1", "company": "City of Hope Comprehensive Cancer Center", "org_type": "医院", "target": "PD-1", "modality": "inhibitor", "importance_level": "低", "total_score": 49.5, "institution_score": 35, "track_score": 75, "milestone_score": 45, "field_heat_score": 65, "bonus_score": 2, "brief_reason": "anti-PD-1为经典ICI抑制剂，modality成熟但非新药；机构为医院/学术中心而非头部药企，研究为preclinical协同机制探索，缺乏临床里程碑，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9624", "id": "3lXM_5wBX1NQZOEH-LK6", "source_drug_name": "anti-PD-1", "title": "TAE226 reprograms immune-cold head and neck tumors to immune-hot, augmenting immunotherapy efficacy", "abstract_text": "Introduction: Current treatment strategies in advanced/recurrent LSCC include chemotherapy, radiation therapy, and immune checkpoint inhibitors (ICI). ICI treatment is associated with durable benefit in about 20% of patients with advanced/incurable platinum-resistant LSCC. There is a clear need to develop strategies to reprogram the tumor microenvironment (TME) from immune-cold to immune-hot to enhance T-cell infiltration and activation that correlate with ICI treatment response. We investigated the therapeutic potential of Focal Adhesion Kinase (FAK) inhibition using a tyrosine kinase inhibitor, TAE226, alone and in combination with anti-PD-1 immune checkpoint blockade, to reprogram the TME and enhance immunotherapeutic responsiveness in a model of platinum-resistant LSCC.\nMethods: LSCC cell lines (SQ20B, SCC17A) were used to assess the inhibitory response to FAK inhibitors using the CCK-8 assay. RNA-seq was performed to evaluate global transcriptional changes and pathway enrichment. Syngeneic MOC2 mouse models were used to assess the therapeutic efficacy of TAE226 in combination with anti-PD-1 therapy. Post euthanization, the xenografts were processed for isolating single cells and performing single-cell RNA sequencing.\nResults: TAE226 significantly reduced LSCC cell proliferation, viability, and wound-healing capacity, indicating potent anti-tumor activity. Bulk RNA-seq and pathway enrichment analyses revealed robust upregulation of interferon and cytokine signaling pathways, consistent with an immune-stimulatory phenotype, while downregulating proliferative and metabolic programs. This dual modulation suggests that TAE226 exerts both tumor-intrinsic anti-proliferative and tumor-extrinsic immune-activating effects. In the MOC2 syngeneic model, the combination of TAE226 and anti-PD-1 produced a synergistic response, resulting in markedly enhanced antitumor signaling and significantly greater tumor regression compared to either monotherapy. Single-cell RNA-seq further demonstrated that TAE226 treatment induced profound TME remodeling, characterized by expansion of cytotoxic CD8⁺ T cells, dendritic cells, and activated macrophages, and depletion of proliferative epithelial and fibroblast-rich stromal clusters. Hallmark pathway analyses highlighted activation of interferon-α/γ, IL2-STAT5, TNFA-NFκB, and complement signaling-consistent with broad activation of innate and adaptive immune programs.\nConclusion: These findings indicate that TAE226 disrupts FAK-mediated adhesion and cytoskeletal signaling, converting the TME from immune-cold to immune-hot and enhancing responsiveness to immune checkpoint blockade and offering a promising therapeutic strategy for platinum-resistant laryngeal cancer.", "source_company": "City of Hope Comprehensive Cancer Center", "source_org_type": "医院", "row_number": 48, "target_meta": "PD1", "MOA_meta": "抑制剂"}, {"drug_name": "antibody-drug conjugate", "company": "Oncodesign Services", "org_type": "公司", "target": "未披露", "modality": "ADC", "importance_level": "低", "total_score": 49.5, "institution_score": 45, "track_score": 85, "milestone_score": 30, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "该记录为CRO公司Oncodesign Services展示其ADC综合临床前服务平台和技术服务，非特定药物候选物，无明确靶点披露。ADC赛道热度高，但作为服务推广而非研发里程碑，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5376", "id": "41XM_5wBX1NQZOEH-LO6", "source_drug_name": "antibody-drug conjugate", "title": "An integrate comprehensive in vitro and in vivo strategies for antibody drug conjugate development", "abstract_text": "Antibody-drug conjugates (ADCs) have transformed the landscape of modern drug development, offering a powerful way to deliver chemotherapy with precision. But translating an ADC concept into a successful candidate requires an integrated approach to identify targets, optimize payload delivery directly to the tumor, and validate efficacy across ex vivo and in vivo preclinical models. The challenge remains to develop improved preclinical tools and select the right pipeline supporting ADC development that will be more predictive of clinical outcome.\nOncodesign Services has generated a comprehensive preclinical platform to support ADC functional characterization by integrating in vitro binding and internalization assays to pharmacokinetics, pharmacodynamics along with efficacy studies in translational models.\nWe offer a wide range of specialized assays and validation tools that examine both antibody and target characterization including a wide range of biological activity (MoA) functional cell-based assays. Available assays include target binding, ADC internalization, payload function and tumor cell kill potency, while available organoid platforms for enhanced translational relevance.\nOncodesign Services includes over 500 tumor models across 35 cancer indications, offering a wide selection of translational models to support your efficacy studies, including patient-derived xenografts (PDX) as well as syngeneic and humanized models.\nIn this poster we show different pre-clinical experiments steps including cellular assays, relevant in vivo models tested with FDA approved ADC payloads in validated target expression tumor combined with imaging technologies and radiopharmaceutical ADCs. The application of preclinical molecular imaging techniques by conjugating an ADC to a fluorescent tag or radioactively labeled improve the identification of effective candidate ADC molecules for therapeutic success.\nFrom concept to proof-of-efficacy, Oncodesign Services present a platform combining biological and pharmacological expertise to accelerate the identification of effective candidate ADC molecules with the best chance of clinical translation and cancer patient benefit.", "source_company": "Oncodesign Services", "source_org_type": "公司", "row_number": 62, "target_meta": "not available", "MOA_meta": "抗体偶联药物"}, {"drug_name": "ALK tyrosine kinase inhibitors", "company": "Japanese Foundation for Cancer Research", "org_type": "研究机构", "target": "未披露", "modality": "inhibitor", "importance_level": "低", "total_score": 49.5, "institution_score": 35, "track_score": 75, "milestone_score": 40, "field_heat_score": 65, "bonus_score": 0, "brief_reason": "该条目讨论ALK-TKI耐药机制中BMF的作用及MCL-1/FOXO1潜在干预策略，但未披露任何具体新药或候选药物靶点。机构为研究机构且内容为机制探索而非药物开发，导致综合重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5052", "id": "HVXM_5wBX1NQZOEH-LS6", "source_drug_name": "ALK tyrosine kinase inhibitors", "title": "CRISPR screening identifies BMF loss as a drug-tolerant persister cell survival factor in ALK-rearranged lung cancer", "abstract_text": "Anaplastic lymphoma kinase (ALK) tyrosine kinase inhibitors (ALK-TKIs) have significantly improved the clinical outcomes of patients with ALK-rearranged non-small cell lung cancer (NSCLC). However, the development of resistance remains a major obstacle to long-term therapeutic success. Drug resistance is believed to develop from drug-tolerant persister (DTP) cells that survive drug treatment. Therefore, understanding the molecular mechanisms underlying DTP formation and survival is critical for developing strategies to overcome resistance and extend patient survival.To identify the factors related to the survival of DTP cells, we conducted a genome-wide CRISPR-Cas9 knockout screening using patient-derived ALK-positive NSCLC cells. From the Crispr screening, we identified the pro-apoptotic factor BMF (Bcl-2 modifying factor) as a critical determinant of DTP formation. BMF expression was rapidly induced following ALK-TKI exposure or dual inhibition of ERK and PI3K signaling, suggesting its role as a mediator of apoptotic induction by ALK-TKIs. Strikingly, BMF knockout cells exhibited impaired apoptosis and an increased fraction of DTPs under ALK-TKI treatment, highlighting its essential function in limiting drug tolerance.Mechanistic studies revealed that pharmacologic or siRNA-mediated inhibition of MCL-1 restored apoptosis and eliminated BMF-deficient DTP cells, underscoring the therapeutic potential of targeting anti-apoptotic pathways. Furthermore, knockdown of FOXO1 resulted in the upregulation of BMF, indicating that FOXO1 acts as a transcriptional repressor of BMF. These findings suggest the existence of a regulatory axis in which FOXO1 suppresses BMF, thereby promoting the survival of DTP cells.In addition, patient tumor samples collected before and after ALK-TKI therapy, together with publicly available datasets, were analyzed to evaluate the clinical relevance of these findings. The clinical analyses revealed that low BMF expression was associated with poor treatment response and shorter overall survival in patients with ALK-positive non-small cell lung cancer (NSCLC). Moreover, BMF genomic loss was found relatively frequently across diverse cancer types, suggesting that BMF deficiency may be a common mechanism contributing to drug tolerance and resistance beyond ALK-driven lung cancer.In summary, our study demonstrates that BMF deficiency promotes the formation of DTP cells and contributes to therapeutic resistance in ALK-positive NSCLC. Importantly, targeting MCL-1 or FOXO1 may be a promising strategy for eradicating DTPs and enhancing the durability of ALK-TKI responses. These findings provide mechanistic insight into the regulation of persister cell apoptosis and highlight actionable vulnerabilities that could be exploited to improve patient outcomes.", "source_company": "Japanese Foundation for Cancer Research", "source_org_type": "研究机构", "row_number": 71, "target_meta": "not available", "MOA_meta": "抑制剂"}, {"drug_name": "Molecule A inhibitor", "company": "Nagoya City University Medical School", "org_type": "大学", "target": "未披露", "modality": "inhibitor", "importance_level": "低", "total_score": 49.5, "institution_score": 35, "track_score": 65, "milestone_score": 55, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "Molecule A 为核苷酸生物合成限速酶抑制剂，机制涉及克服lenvatinib等TKI耐药的代谢重编程，但靶点具体未披露。大学机构+preclinical协同效应研究，整体创新性和开发阶段限制了重要性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4981", "id": "xVXM_5wBX1NQZOEH-LS6", "source_drug_name": "Molecule A inhibitor", "title": "Genome-wide CRISPR-Cas9 screen identifies genes conferring lenvatinib resistance in hepatocellular carcinoma", "abstract_text": "Background: Tyrosine kinase inhibitors (TKIs), such as lenvatinib, sorafenib, and regorafenib, form a key component of current systemic therapy for advanced hepatocellular carcinoma (HCC). However, intrinsic and acquired resistance significantly diminish their clinical benefit. Although multiple signaling pathways have been implicated in TKI response, the molecular determinants that sustain broad TKI resistance remain incompletely defined. To uncover these mechanisms, we performed an unbiased genome-wide genetic interrogation in a mouse HCC cell line.\nMaterials and Methods: We established a murine HCC cell line from melanocortin-4 receptor-deficient mice fed a high-fat diet. These cells exhibited pronounced intrinsic resistance to lenvatinib. To identify genes underlying this resistance, we performed a genome-wide CRISPR-Cas9 knockout screen using a pooled sgRNA library. Top candidates were prioritized by guide depletion scores and validated using siRNAs and shRNAs. Transcriptomic and proteomic analyses were conducted to define downstream pathways. To assess therapeutic relevance, we tested inhibitors targeting enzymes within this network and evaluated their combinatorial effects with lenvatinib and other TKIs across multiple cancer cell lines.\nResults: The CRISPR screen identified PCIF1, an mRNA methyltransferase responsible for installing m6Am modification at the 5′ cap, as a leading determinant whose loss markedly sensitized human HCC cells to lenvatinib in both in vitro assays and in vivo tumor models. Integrative multi-omics analysis revealed that PCIF1 regulates a MYBL2-driven transcriptional program that converges on nucleotide metabolic pathways. Within this downstream network, a rate-limiting enzyme in nucleic acid biosynthesis (Molecule A) emerged as a key effector. Pharmacological inhibition of Molecule A exhibited potent synergistic effects not only with lenvatinib but also with additional TKIs, enhancing drug sensitivity and suppressing proliferation across human HCC and other cancer cell lines. Expression of Molecule A was significantly associated with lenvatinib resistance, underscoring its potential relevance as a biomarker and therapeutic target beyond the PCIF1-MYBL2 regulatory axis.\nConclusion: Our findings demonstrate that, even when proliferation appears unchanged, TKI exposure imposes a metabolic stress that drives a rewiring of nucleotide biosynthesis and a pronounced dependency on Molecule A. This adaptive shift is observed across distinct TKIs and cancer types, indicating that altered nucleotide metabolism represents a broadly conserved mechanism of drug resistance. Because clinically approved inhibitors of Molecule A are already available, these results provide a strong rationale for therapeutic repositioning strategies aimed at overcoming TKI resistance in hepatocellular carcinoma.", "source_company": "Nagoya City University Medical School", "source_org_type": "大学", "row_number": 79, "target_meta": "not available", "MOA_meta": "抑制剂"}, {"drug_name": "anti-PD1", "company": "Hospital for Sick Children", "org_type": "医院", "target": "PD-1", "modality": "inhibitor", "importance_level": "低", "total_score": 49.5, "institution_score": 35, "track_score": 75, "milestone_score": 40, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "anti-PD1为已知PD-1抑制剂，在priMMRD胶质瘤亚组中显示异质性免疫治疗应答，其中priMMRD1亚组2年总生存率达75%。因研发机构为医院而非药企、摘要为临床回顾性分析而非新药开发里程碑，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1756", "id": "7Z7M_5wBZznHJdnt_W3O", "source_drug_name": "anti-PD1", "title": "Hypermutation patterns shape tumorigenesis and immunotherapy response in mismatch repair deficient glioma", "abstract_text": "Primary mismatch repair deficient (priMMRD) glioma are deadly cancers comprising 5-10% of gliomas in children and young adults. PriMMRD glioma are characterized by universal hypermutation, resistance to chemo-irradation, and striking, but hetergeonous, responses to anti-PD1 immunotherapy. To elucidate the impact of replication-error driven mutagenesis on priMMRD glioma evolution and their heterogenous clinical courses, we analyzed genomic, methylomic, immune, and clinical data on a large cohort of priMMRD glioma (n=162) from the the International Replication Repair Deficiency Consortium. MMRD contributed to high microsatellite instability and hypermutation resulting in global DNA hypomethylation compared to non-MMRD gliomas and potentially affecting their classification. Recurrent somatic driver mutations in replicative polymerases and IDH1 stratified priMMRD gliomas into 3 distinct genetic and clinical subgroups: priMMRD1 (MMRD+POLE/POLD1, 56%), priMMRD2 (MMRD-only, 27%), and priMMRD3 (MMRD+IDH1, 17%). PriMMRD1 gliomas, which harbor complete replication repair deficiency, originated from germline biallelic MMRD (CMMRD), occurred at young ages, and exhibited ultrahypermutation. PriMMRD2 gliomas were enriched for monoallelic germline MMRD (Lynch syndrome) and older ages. Finally, IDH1-driven priMMRD3 gliomas harboured germline mutations in MutSα (MSH2/MSH6), lower mutation burden, and distinct imaging patterns. Subgroups also utilized different mechanisms of genomic instability: while priMMRD1 gliomas harboured frequent point mutations in glioma drivers, priMMRD2 and priMMRD3 gliomas had higher rates of copy alteration in the same genes, including CDKN2A (P<0.0001) and PTEN (P<0.0001). Driver mutations observed in MMRD-driven gliomagenesis could be explained by the specific trinucleotide contexts that compose MMRD mutational signatures. Hotspot mutations in TP53 and IDH1 occurred in contexts commonly mutated by MMRD, while pediatric glioma drivers (BRAF/H3-3A), which do not arise from frequently mutated contexts, were rare. Using mutational signatures and variant allele fractions, we built a model of MMRD gliomagenesis where TP53 mutations occur early, followed by secondary mutations in POLE/POLD1, IDH1, and other glioma drivers. PriMMRD glioma subgroups differed in their immune microenvironment and response to immunotherapy: priMMRD1 gliomas were associated with the highest 2-year overall survival on anti-PD1 monotherapy (75%), exhibited pro-immune expression signatures, and high CD8+ T-cell infiltration, contrasting priMMRD2 (24%) and priMMRD3 gliomas (0%). These findings suggest that MMRD mutagenesis shapes the unique landscape of priMMRD glioma through driver mutation acquisition and responses to immunotherapy, providing a rational approach for the refinement of subgroup-specific immunotherapy combinations.", "source_company": "Hospital for Sick Children", "source_org_type": "医院", "row_number": 92, "target_meta": "PD1", "MOA_meta": "抑制剂"}, {"drug_name": "RPT-E-037", "company": "Wayne State University", "org_type": "大学", "target": "NAMPT", "modality": "inhibitor", "importance_level": "低", "total_score": 49.5, "institution_score": 30, "track_score": 75, "milestone_score": 60, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "RPT-E-037为新型双曲线NAMPT抑制剂，靶向NAD补救途径以干扰KRAS驱动肿瘤代谢，与pan-RAS抑制剂协同作用于PDAC模型。机构为大学而非商业公司导致分数较低，尽管preclinical协同效应强且针对耐药模型，但整体开发阶段早期且非热门靶点组合。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8820", "id": "P57M_5wBZznHJdnt_W3O", "source_drug_name": "RPT-E-037", "title": "Preclinical evaluation of a novel hyperbolic NAMPT inhibitor in combination with pan-RAS targeted therapies in pancreatic ductal adenocarcinoma", "abstract_text": "Background: Pancreatic ductal adenocarcinoma (PDAC) remains highly lethal, driven by near-universal KRAS mutations and profound metabolic dependence on nicotinamide adenine dinucleotide (NAD). NAMPT, the rate-limiting enzyme of the NAD salvage pathway, is frequently upregulated in KRAS-driven tumors, suggesting metabolic co-dependence. We evaluated whether simultaneous blockade of NAMPT and KRAS signaling enhances antitumor efficacy in PDAC.\nMethods: KRAS-NAMPT expression correlations were analyzed in TCGA PDAC samples (n=179). Multiple KRAS-mutant PDAC cellular models, including KRASG12C inhibitor, KRASG12D inhibitor, and pan-RAS inhibitor (RMC6236)-resistant lines were treated with the hyperbolic NAMPT inhibitor RPT-E-037, RMC6236, or both. Antitumor activity was assessed in 2D viability assays, 3D spheroid cultures, and patient-derived 2D/3D co-culture systems. Drug interactions were calculated using combination index (CI) analysis.\nResults: TCGA analysis revealed a fairly strong positive correlation between KRAS and NAMPT expression (Spearman ρ=0.59). RMC6236-resistant PDAC cells displayed increased NAMPT expression and heightened sensitivity to RPT-E-037 compared to parental cells. Similar NAMPT upregulation and enhanced NAMPT inhibitor sensitivity were observed in KRASG12C and KRASG12D inhibitor-resistant models. Across KRAS-mutant PDAC lines, RPT-E-037 combined with RMC6236 produced robust synergy (CI<1) in both 2D and 3D cultures. In patient-derived PDAC co-culture systems, the combination significantly reduced tumor mass, dismantled compact spheroid architecture, and disrupted tumor-stroma interactions more effectively than either agent alone. KRASG12D-mutant metastatic patient rapid autopsy tissue-derived and KPC mice tumor-derived subcutaneous and orthotopic xenograft studies with the combination are ongoing.\nConclusion: Dual inhibition of NAMPT-mediated NAD biosynthesis and KRAS signaling yields synergistic antitumor activity in PDAC, including models resistant to KRAS-targeted therapies. These findings support NAMPT-KRAS co-dependency as a therapeutically actionable vulnerability and justify further translational and in vivo studies to guide clinical development and biomarker-based patient selection.\"Generative AI was used for improving the language of the abstract\".", "source_company": "Wayne State University", "source_org_type": "大学", "row_number": 263, "target_meta": "NAMPT", "MOA_meta": "抑制剂"}, {"drug_name": "CAR T cell therapy", "company": "City of Hope", "org_type": "医院", "target": "未披露", "modality": "CAR", "importance_level": "低", "total_score": 49.5, "institution_score": 45, "track_score": 85, "milestone_score": 30, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "该CAR T细胞疗法针对成人ALL一线治疗，但摘要未提供具体靶点或机制细节，仅提及炎症和免疫代谢特征支持其应用。City of Hope作为知名癌症医院在细胞治疗领域有积累，但非头部药企且信息严重缺失导致开发阶段和里程碑价值判断低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11007", "id": "5FXM_5wBX1NQZOEH-LC5", "source_drug_name": "CAR T cell therapy", "title": "First line CAR T cell therapy for adults with ALL is supported by distinct inflammatory and immunometabolic features", "abstract_text": "There is no abstract associated with this presentation.", "source_company": "City of Hope", "source_org_type": "医院", "row_number": 291, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "selective YTHDF2 inhibitor", "company": "Saveetha Dental College and Hospitals", "org_type": "医院", "target": "YTHDF2", "modality": "inhibitor", "importance_level": "低", "total_score": 49.5, "institution_score": 20, "track_score": 85, "milestone_score": 45, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "药物为针对YTHDF2的selective小分子抑制剂，通过阻止p53降解抑制OSCC肿瘤进展，机制新颖且靶点在m6A调控领域具潜力。机构为印度牙科医院/学术机构，非主流药企，导致机构分低；虽preclinical显示器官芯片和PDOs抗肿瘤效应，但无公司推进迹象，整体开发阶段早期，总分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8580", "id": "U1XM_5wBX1NQZOEH-LG5", "source_drug_name": "selective YTHDF2 inhibitor", "title": "Targeting the oncogenic RNA m6A reader YTHDF2 inhibits oral squamous cell carcinoma by preventing p53 degradation", "abstract_text": "Background: The N6-methyladenosine (m6A) RNA modification machinery has emerged as a critical modulator in cancer biology, however, the function of m6A “reader” proteins in oral squamous cell carcinoma (OSCC) is not fully understand. YTH domain family protein 2 (YTHDF2) is a prominent m6A-binding protein (m6A “reader”) that facilitates the degradation of methylated mRNAs and has been associated with tumorigenesis by targeting destabilization on clusters of tumor suppressor mRNAs. Nevertheless, the exact mechanism how YTHDF2 promotes OSCC proliferation and regulates p53 activity is in dire lack of elucidation. This study investigated the oncogenic role of YTHDF2 in OSCC and evaluated its potential as both a diagnostic biomarker and a therapeutic target.\nMethods: The mRNA and protein levels of YTHDF2 were examined in OSCC tissues, matched adjacent non-cancerous specimens as well as OSCC cell lines by quantitative real-time PCR (qRT-PCR) and Western blot. Furthermore, the TCGA-OSCC dataset were employed to evaluate YTHDF2 expression, its clinicopathological characteristics and prognostic value. Functional assays including proliferation, colony formation and wound-healing assays were performed to evaluate the oncogenic phenotypes in YTHDF2-depleted OSCC cell lines. The antitumor effects were examined in vitro via OSCC cell lines and patient-derived organoids (PDOs) derived from OSCC patients who received a selective YTHDF2 inhibitor.\nResults: YTHDF2 was remarkably up-regulated in OSCC tissues and cell lines compared with non-tumor tissues and normal cells, P < 0.001. Overexpression of YTHDF2 is correlated with OSCC development, progression and poor prognosis. YTHDF2 knockdown dramatically impaired OSCC cell proliferation, migration and tumorsphere formation. Functionally, YTHDF2 physically interacted with m6A-modified p53 transcripts and promoted their degradation. Inhibition of YTHDF2 significantly promoted the stability and protein expression of p53. YTHDF2 inhibitor impeded growth, migration, colony formation, tumorsphere and organoid development of cancer cells.\nConclusions: Our results recognize YTHDF2 as an oncogenic m6A reader promoting the OSCC progression by increasing p53 mRNA degradation. Our findings indicate that YTHDF2 can be exploited therapeutically and tumor suppressively as a candidate antitumor approach in OSCC.", "source_company": "Saveetha Dental College and Hospitals", "source_org_type": "医院", "row_number": 368, "target_meta": "YTHDF2", "MOA_meta": "抑制剂"}, {"drug_name": "ST6GAL1 enhanced CAR-T cells", "company": "Herbert Wertheim College of Medicine", "org_type": "大学", "target": "未披露", "modality": "CAR", "importance_level": "低", "total_score": 49.5, "institution_score": 25, "track_score": 75, "milestone_score": 60, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "通过ST6GAL1过表达进行糖基化工程改造的CAR-T细胞，掩蔽Gal-3结合位点以减少凋亡并提升持久性和抗肿瘤活性，但靶点未明确披露。大学机构分数较低，preclinical小鼠模型显示显著改善但无临床阶段，综合总分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5214", "id": "OZ7ECZ0BZznHJdntvNYd", "source_drug_name": "ST6GAL1 enhanced CAR-T cells", "title": "ST6GAL1 enhanced CAR-T cells improve persistence and antitumor efficacy in DLBCL", "abstract_text": "Diffuse large B cell lymphoma (DLBCL) is the most common and aggressive B cell lymphoma, with poor outcomes for patients who relapse or are refractory to treatment. Chimeric antigen receptor (CAR)-T cell therapy offers a promising therapeutic option, yet limited persistence and functional impairment remain major barriers to durable responses. Galectin (Gal)-3, a carbohydrate-binding protein highly expressed in the DLBCL microenvironment, has been implicated in T cell dysfunction, but its role in CAR-T cell impairment has not been fully defined. We hypothesized that Gal-3 binds to CAR-T cell surface glycans, promoting apoptosis and loss of effector function. ELISA revealed significantly elevated Gal-3 levels in serum from DLBCL patients versus healthy controls (p<0.001). Flow cytometry confirmed strong Gal-3 binding to CAR-T cells, which correlated with increased apoptosis (p<0.01). To overcome this, we engineered CAR-T cells to overexpress the α2,6 sialyltransferase ST6GAL1 (ST6OE)CAR-T cells, which adds α2,6-sialic acids known to mask Gal-3-binding glycans. ST6OECAR T cells displayed markedly reduced Gal-3 binding, lower apoptosis (p<0.001), and improved viability and cytotoxicity in Gal-3high DLBCL co-cultures. Cytokine profiling further revealed that control CAR-T cells secreted elevated levels of interleukin-5 (IL-5),a Th2-associated cytokine linked to reduced antitumor activity. In contrast, ST6OE CAR-T cells exhibited significantly lower IL-5 production (p<0.01), indicating a shift toward amore cytotoxic, Th1-like functional profile. In a DLBCL xenograft model, ST6OE CAR-T treatment significantly reduced tumor burden and improved survival compared to control CAR-T cells (p<0.001). These findings demonstrate that ST6GAL1 overexpression mitigates apoptosis and IL-5-associated dysfunction, enhancing CAR-T cell persistence and antitumor efficacy. Glycoengineering CAR-T cells via ST6GAL1 provides a novel strategy to improve therapeutic outcomes for patients with DLBCL.", "source_company": "Herbert Wertheim College of Medicine", "source_org_type": "大学", "row_number": 419, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "arecoline hydrobromide", "company": "Universidad Argentina de la Empresa (UADE)", "org_type": "大学", "target": "ACAT1", "modality": "inhibitor", "importance_level": "低", "total_score": 49.5, "institution_score": 25, "track_score": 65, "milestone_score": 70, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "药品为ACAT1抑制剂，靶向酮体代谢这一前列腺癌进展中的代谢脆弱性，在体外和体内模型中显示抑制肿瘤生长效果。机构为大学非商业实体得分较低，赛道为代谢靶向治疗有一定新颖性但非最热门，preclinical阶段有较强体内外数据但无临床进展，总分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9172", "id": "x1XM_5wBX1NQZOEH-LG6", "source_drug_name": "arecoline hydrobromide", "title": "Exploiting ketone body metabolism as a therapeutic vulnerability in prostate cancer", "abstract_text": "Prostate cancer (PCa) progression remains a major clinical challenge with limited therapeutic options, and the complexity of metabolic pathways fueling advanced PCa rests poorly understood. We have identified a shift from glycolysis to ketone body (KB) metabolism in castration-resistant PCa (CRPC), with an upregulation of ketolytic/ketogenic enzymes. From these, ACAT1 is a potential therapeutic candidate, as its expression is elevated in aggressive PCa and associates with unfavorable clinical outcomes. Here, we investigated the contribution of the bone niche -the dominant PCa metastatic site- to KB metabolism during PCa progression and evaluated ACAT1 inhibition as a treatment strategy for advanced disease. Co-culture experiments between PCa cells and bone progenitors (MC3T3, Raw264.7) were used to evaluate bone-driven metabolic adaptations. To validate in vivo the effect of the bone niche, we implanted MDA PCa patient-derived xenograft (PDX) 183 either intrafemorally (i.f.) or subcutaneously (s.c.) in sham or castrated CB17 SCID mice. We assessed cell viability in PCa cells lines and in PDX-derived organoids (PDX.DO), treated with increasing concentrations of ACAT1 inhibitor, arecoline hydrobromide (AH). ACAT1 and phospho-ACAT1 levels were measured by Western blot and immunofluorescence. Intracellular KB and ATP content were quantified by luciferase-based assays. Lipid uptake and accumulation were quantified by flow cytometry using Bodipy probes. In vivo, mice bearing MDA PCa PDXs 183, 203 and 173 were treated with AH (50 mg/kg/day i.p., 21 days). Tumor volume, KB content, and ACAT1 modulation were evaluated. We observed transcriptional activation of lipid and KB metabolism in PC3 cells from PCa-bone co-cultures, and consistently, in i.f. PDXs compared to matched s.c. tumors, alongside a significant increase in ACAT1 expression levels. Castration dynamically modulated ACAT1 levels in MDA PCa 183 tumors growing i.f., with initial downregulation followed by restoration over time, underscoring KB metabolism as a mechanism of resistance within the bone niche. Functional studies showed that AH treatment reduced cell viability in PC3, C42B, and 22Rv1 cells, as well as PDX.DO, decreased ACAT1 and phospho-ACAT1 expression, lowered KB levels, and altered lipid dynamics by increasing lipid accumulation, uptake, and decreasing ATP content (P<0.05). In vivo, AH treatment in MDA PCa 183 tumors led to a significant reduction in tumor volume and intratumoral KB content (P<0.05). Moreover, in the CRPC model MDA PCa 203 -derived from a longitudinal sample of the same patient as 183-, and in the aggressive hormone-naïve model MDA PCa 173, AH treatment significantly reduced both tumor volume and KB content (P<0.05). In conclusion, our findings reveal KB metabolism as a critical vulnerability in PCa progression, with ACAT1 emerging as a druggable target whose inhibition disrupts tumor growth and metabolic fitness.", "source_company": "Universidad Argentina de la Empresa (UADE)", "source_org_type": "大学", "row_number": 453, "target_meta": "ACAT1,SOAT1", "MOA_meta": "抑制剂"}, {"drug_name": "nanoconjugate blocking laminin-411", "company": "Cedars-Sinai Health Sciences University", "org_type": "大学", "target": "laminin-411", "modality": "nanoconjugate", "importance_level": "低", "total_score": 49.5, "institution_score": 35, "track_score": 75, "milestone_score": 45, "field_heat_score": 65, "bonus_score": 3, "brief_reason": "药物为基于聚苹果酸的纳米缀合物，通过AON阻断laminin-411（α4β1γ1）链以激活GBM局部免疫响应。大学机构分数较低，preclinical小鼠模型显示生存延长及免疫激活但无临床阶段，赛道有纳米递送+肿瘤微环境调控一定创新性，总分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10785", "id": "EVXM_5wBX1NQZOEH-LK6", "source_drug_name": "nanoconjugate blocking laminin-411", "title": "Glioblastoma treatment with multifunctional nanodrug inhibiting laminin-411 activates local immune response, increases survival of mice and reveals AI-selected immune molecular pathways", "abstract_text": "Introduction: Cancer microenvironment influences tumor growth, invasion, and escape from immune surveillance. Glioblastoma (GBM) extracellular matrix (ECM) especially laminins play an important role in tumor progression. We previously observed a correlation in GBM samples from 130 patients between increased expression of ECM laminin-411 (α4β1γ1) and faster tumor recurrence with decreased patient survival. Laminin-411 is a basement membrane component that can also modulate immune response through Notch signaling. We developed novel nanoconjugate (NC) blocking laminin-411 that can activate GBM local immune system after brain delivery.\nMethods: NC was based on non-toxic poly (β-L-malic acid, P) with covalently attached antisense oligonucleotides (AON) against laminin-411 α4 and β1 chains, as well as trileucine (LLL) peptide for endosomal escape, AP-2 peptide for blood-brain barrier (BBB) crossing and GBM cell targeting. The NC was thoroughly characterized and was intravenously administered to mice (5 injections) with intracranial syngeneic GL261 GBM. The NC selected for treatment had the structure [P/mPEG5000(2%)/LLL(40%)/AON(α4β1)(2.0%)/AP-2(2%)]. Tumor RNA sequencing (RNA-seq) was analyzed by bioinformatics with artificial intelligence and validated for select genes by immunohistochemistry. Immune cell populations were analyzed by flow cytometry.\nResults: NC treatment in vivo suppressed GBM growth and significantly prolonged animal survival. RNA-sec analysis after treatment with NC suppressing tumor laminin-411 suggested anti-tumor effect with upregulation of apoptotic Casp3, Ifng, Tnf, Il1a, and Il1b genes and reduction of glioma proliferation markers and oncogenes EGFR, c-Myc, Klf4, Irf4, and Ki-67, as well as Notch ligand Dll3. Ingenuity pathway analysis artificial intelligence module AI interpret predicted activation of inflammatory pathways involved in cell signaling during immune responses, pathways related to adhesion and migration of immune cells, and general immune response. In agreement with these data, protein validation showed decreased Ki-67 and Dll3, and increased T cell marker CD4, inflammatory markers IFNγ and TNFα, and anti-tumor M1 macrophage marker NOS2/iNOS. Interestingly, the immunostaining for markers of GBM stem cells, CD133 and nestin, was markedly decreased upon treatment. Flow cytometry also suggested activation of immune response after NC administration.\nConclusion: We describe a novel GBM treatment strategy via NC crossing BBB and targeting critical ECM and immune components of tumor microenvironment that are largely independent of heterogeneous genetic mutations in glioblastoma. Support: NIH grants R01 CA284247, R01 CA188743, R01 CA206220, R01 CA209921, R01 EY013431", "source_company": "Cedars-Sinai Health Sciences University", "source_org_type": "大学", "row_number": 503, "target_meta": "laminin", "MOA_meta": "结合"}, {"drug_name": "STING agonist", "company": "University of Southern California", "org_type": "大学", "target": "未披露", "modality": "STING agonist", "importance_level": "低", "total_score": 49.5, "institution_score": 30, "track_score": 85, "milestone_score": 40, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "STING agonist 通过激活TBK1/IKKβ磷酸化CAD，抑制嘧啶合成并增强化疗敏感性，机制新颖但仅为通用工具药而非特定候选药物。大学机构基础研究，preclinical机制探索无具体分子或临床推进，赛道热门但整体开发阶段早期。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9159", "id": "RJ7ECZ0BZznHJdntvNYd", "source_drug_name": "STING agonist", "title": "TBK1/IKKβ-mediated CAD phosphorylation links pyrimidine synthesis blockade and chemosensitization to innate immune activation", "abstract_text": "Metabolic reprogramming is a hallmark of cancer. Aberrantly-activated metabolic enzymes fuel tumor progression through multiple mechanisms, including tumor cell proliferation, metastasis and drug resistance. Elucidating the regulatory mechanism of metabolic enzymes in cancer is thus of vital importance, which will pave a way to novel anti-tumor therapies. The first three steps of de novo pyrimidine synthesis are mediated by a multi-functional enzyme known as carbamoyl-phosphate synthetase 2, aspartate transcarbamylase, and dihydroorotase (CAD). Our lab have identified CAD as a protein deamidase that deamidates the NF-κB transcriptional factor RelA, shunting RelA from mediating the transcription of inflammatory cytokines to glycolytic enzymes. CAD thereby acts as a cellular metabolic node that fuels cancer cell proliferation by mediating pyrimidine synthesis and aerobic glycolysis. Indeed, CAD has been characterized as a critical oncogenic factor in a variety of malignancies. However, whether and how CAD is regulated by innate immune response remain unexplored. In this study, we report that innate immune activation dramatically impairs CAD enzymatic activity in colon cancer cells. Mechanistically, CAD is phosphorylated at multiple residues by two key innate immune protein kinases, TANK-binding kinase-1 (TBK1) and inhibitor of NF-κB kinase-β (IKKβ). TBK1 / IKKβ-mediated phosphorylation significantly attenuates both pyrimidine synthetase and protein deamidase activity of CAD, subsequently suppressing colon cancer cell metabolic reprogramming and proliferation. Furthermore, TBK1 / IKKβ-mediated CAD phoshorylation results in pyrimidine depletion and an imbalance in cellular nucleotide pool, which sensitizes colon cancer cells to DNA damage agents. Pharmacological activation of innate immune signaling by stimulator of interferon gene (STING) agonist can thereby inhibit intratumoral CAD activity and boost chemotherapy agents-induced DNA damage, highlighting a novel combination therapy. Besides, in a panel of cancer cell lines in which TBK1 acts as an oncogene, TBK1 is switched to activate CAD via growth factor signaling pathway, implicating context-dependent roles of TBK1 in regulating CAD. In summary, our study reveals an unprecedented crosstalk that places pyrimidine synthesis as a downstream ramification of innate immune activation. These findings provide fresh insights into how innate immune signaling reshapes tumor metabolic landscape, and offer a mechanistic rationale for combining STING agonists with chemotherapy as a highly potent approach to improve cancer treatment.", "source_company": "University of Southern California", "source_org_type": "大学", "row_number": 508, "target_meta": "not available", "MOA_meta": "激动剂"}, {"drug_name": "Vartumab", "company": "The University of British Columbia", "org_type": "大学", "target": "oncofetal chondroitin sulfate (ofCS)", "modality": "antibody", "importance_level": "低", "total_score": 49.5, "institution_score": 30, "track_score": 85, "milestone_score": 40, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "Vartumab靶向oncofetal chondroitin sulfate (ofCS)，这是一种pan-cancer新型糖胺聚糖靶点，具有first-in-class潜力和肿瘤特异性。机构为大学而非商业公司导致institution_score较低，摘要embargoed仅体现preclinical阶段临床验证，整体开发阶段早期，总分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/12037", "id": "rlXM_5wBX1NQZOEH-LK6", "source_drug_name": "Vartumab", "title": "Clinical validation of a first-in-class pan-cancer antibody Vartumab targeting oncofetal chondroitin sulfate", "abstract_text": "Abstract is embargoed at this time.", "source_company": "The University of British Columbia", "source_org_type": "大学", "row_number": 600, "target_meta": "CS", "MOA_meta": "抗体"}, {"drug_name": "WEE1 inhibitor", "company": "Children's Hospital Los Angeles", "org_type": "医院", "target": "WEE1", "modality": "inhibitor", "importance_level": "低", "total_score": 49.5, "institution_score": 30, "track_score": 75, "milestone_score": 45, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "药品为WEE1抑制剂，靶向PAX3-FOXO1融合阳性横纹肌肉瘤中WEE1激酶调控的细胞周期与侵袭。机构为医院/研究型，preclinical 3D模型显示抑制WEE1可减缓生长与侵袭，但无临床阶段进展，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10931", "id": "xlXM_5wBX1NQZOEH-LK6", "source_drug_name": "WEE1 inhibitor", "title": "Cell cycle regulation by PAX3-FOXO1 via WEE1 kinase in fusion-positive rhabdomyosarcoma", "abstract_text": "IntroductionFusion-positive rhabdomyosarcoma (FPRMS) is a highly aggressive form of the most common childhood muscle cancer, rhabdomyosarcoma. A distinct genetic signature, the PAX3-FOXO1 (P3F) fusion gene, characterizes a subtype of the most common pediatric soft tissue sarcoma. We aim to understand the collective cell invasion by determining how leader-follower cellular cooperation, P3F signaling, and the cell-cycle checkpoint kinase WEE1 drive tumor growth and invasion, and whether inhibiting WEE1 can blunt these behaviors.\nBrief Experimental ProceduresTo understand the collective cell invasion of FPRMS, we utilize a 3D \"mini-tumor\" (spheroid) model that recapitulates leader cells at the invasive front and rapidly proliferating follower cells behind them. We paired this with live-cell reporters of cell-cycle checkpoint activity and proliferation. We analyzed the transcriptome of FPRMS cells with P3F knockdown (PFKD) to confirm whether P3F regulates cell cycle checkpoints and DNA replication. Additionally, we employ ChIP-seq to identify the P3F-regulated genes and pharmacological WEE1 inhibition.\nResultsOur preliminary data show that follower cells exhibit higher P3F expression, increased proliferation, and elevated WEE1 activity relative to other regions, consistent with a fast-cycling compartment that mechanically supports leader-directed invasion. These findings suggest that P3F upregulates WEE1-dependent programs, which fuel follower growth and cooperative invasion. Additionally, we use P3F knockdown to demonstrate, via RNA-seq, the Negative enrichment of gene sets associated with the G1/S transition and DNA replication in PFKD FPRMS cells. PAX3-FOXO1 regulates cell cycle progression by S-phase arrest. Furthermore, P3F regulates cell cycle progression by reducing the expression of pCDK2 and the double-strand break regulatory gene γH2A.X.\nConclusionsTogether, the data support a model in which P3F-driven WEE1 signaling sustains the follower population that powers collective invasion in FPRMS. Targeting WEE1 slows growth and invasion in our 3D model, suggesting that WEE1 inhibition is a therapeutic strategy worthy of further evaluation in patient-derived specimens and preclinical studies.", "source_company": "Children's Hospital Los Angeles", "source_org_type": "医院", "row_number": 613, "target_meta": "WEE1", "MOA_meta": "抑制剂"}, {"drug_name": "CDK4/6 inhibitors", "company": "Lester & Sue Smith Breast Center", "org_type": "医院", "target": "CDK4/6", "modality": "inhibitor", "importance_level": "低", "total_score": 49.5, "institution_score": 30, "track_score": 75, "milestone_score": 45, "field_heat_score": 65, "bonus_score": 0, "brief_reason": "CDK4/6抑制剂为成熟靶点和药物类别，主要研究其耐药机制及潜在生物标志物MCM2/LC。机构为医院/研究型中心且内容属回顾性分析而非新药开发，导致整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1189", "id": "1VXM_5wBX1NQZOEH-LK6", "source_drug_name": "CDK4/6 inhibitors", "title": "MCM2 and the origin licensing complex: A putative node of ER+/HER2- breast cancer therapy resistance", "abstract_text": "Background: The use of CDK4/6 inhibitors (CDK4/6i) in combination with endocrine therapy (ET) has revolutionized treatment practices for advanced and high-risk ER+/HER2- breast cancer (BC) via effective inhibition of cell cycle activation. However, the vast majority of patients eventually progress on these therapies, underscoring the need for new treatment strategies to select patients, monitor response, and target novel therapeutic vulnerabilities. We previously reported that high expression of MCM2 and its origin licensing complex (LC) is enriched in primary tumors refractory to CDK4/6i (SABCS22-P2-03-10). LC factors are transcriptionally regulated by E2F/MYC-driven programs, which are activated by diverse drivers of resistance. We propose that MCM2/LC expression may be a biomarker reflecting multiple ET and CDK4/6i resistance mechanisms, due to its role in cell cycle activation.\nMethods: A retrospective review was conducted on a real-world, treatment-naive ER+/HER2- BC cohort of 1,960 largely metastatic patients with biopsies from breast or other sites (~50% each) that underwent NGS profiling (DNA: 592-gene panel/whole-exome; RNA: whole-transcriptome) at Caris Life Sciences. Tumors were stratified by MCM2 or LC gene set mRNA into Q4 (high) versus Q1 (low; n=490 each), balanced for ET/CDK4/6i exposure, MSI-H, and TMB-H. Histology, PAM50, mutations (mut), gene amplifications(amp) and deletions(del), and differential gene expression were analyzed. Chi-square, Fisher’s Exact, or Mann-Whitney U tests were performed with Benjamini-Hochberg FDR for molecular variables (q<0.05).\nResults: MCM2-high vs -low tumors were LumB-dominant (LumB 85.5% vs 39.8%; LumA 5.3% vs 56.3%, p<1e-63) with less lobular histology (6.1% vs 17.1%, p=0.0001). Transcriptomically, PI3K/AKT/mTOR, E2F/MYC targets, G2M checkpoint, and DNA repair hallmark pathways were enriched in MCM2-high (all FDR q<0.05). Genomically, MCM2-high harbored a higher frequency of TP53mut (32.6% vs 16.6%, q=4e-6), RB1mut (5.8% vs 1.2%, q=0.052), CCND1amp (26% vs 6%, q=4.5e-11), FGF3/4/19amp (~25% vs ~6%, q≤2.2e-10), MYCamp (5.4% vs 0.8%, q=0.0136), and CDKN2A/Bdel (CDKN2A 29.3% vs 15.5%, q=6.9e-4; CDKN2B 17.5% vs 7.3%, q=1.38e-3). Notably, MCM2 and MKI67 gene expression were highly correlated (Spearman’s ρ=0.77, p<0.05). Very similar results were found for LC-high vs -low tumors.\nConclusions: In ER+/HER2- BC, high MCM2/LC is associated with LumB subtype, E2F/MYC and cell cycle activation, selection of TP53 and RB1 mutations, and CCND1/MYC/FGF amplifications. Our findings suggest that MCM2 or LC mRNA may act as a surrogate marker for a network of oncogenic pathways previously identified to drive endocrine and CDK4/6i resistance. Future studies will evaluate MCM2/LC beyond proliferation, as a predictive biomarker for CDK4/6i-based regimens, as we have previously shown in the primary ET-treated setting (SABCS24-P1-03-20).", "source_company": "Lester & Sue Smith Breast Center", "source_org_type": "医院", "row_number": 627, "target_meta": "CDK4,CDK6", "MOA_meta": "抑制剂"}, {"drug_name": "[89Zr]Zr-DFO-Fab14", "company": "University of Alabama at Birmingham", "org_type": "大学", "target": "CD68", "modality": "RLT imaging agent", "importance_level": "低", "total_score": 49.5, "institution_score": 35, "track_score": 65, "milestone_score": 55, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "药物为靶向人CD68的放射性免疫PET探针，可特异性显像人源TAMs。大学机构得分较低，尽管免疫微环境显像在肿瘤研究中有价值，但preclinical阶段且非治疗性探针导致总体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6345", "id": "6lXM_5wBX1NQZOEH-LK6", "source_drug_name": "[89Zr]Zr-DFO-Fab14", "title": "ImmunoPET reveals tumor-associated macrophages in humanized MDA-MB-231 models", "abstract_text": "Background: Tumor-associated macrophages (TAMs) represent a major component of the tumor immune microenvironment and are associated with tumor progression and therapeutic resistance. Noninvasive detection of TAMs can provide valuable insight into immune infiltration and guide immunotherapy development. However, current macrophage imaging agents lack specificity for human pan-macrophages. In this study, we aim to image human macrophages in a humanized mouse model using our specific macrophage-targeted probe.\nMethods: We developed a human-specific CD68-Fab fragment (Fab14) and radiolabeled it with zirconium-89 to obtain [89Zr]Zr-DFO-Fab14. Humanized NSG-SGM3 and control NSG-SGM3 mice were implanted with MDA-MB-231 triple-negative breast cancer cells into the mammary fat pad. When tumors were palpable, mice were injected intravenously with 6.25 µg of human-specific, macrophage-selective [89Zr]Zr-DFO-Fab14 (~30 µCi per mouse). PET imaging was performed at 2-, 24- and 48-hours post-injection (p.i.), and radiotracer uptake was quantified using SUVmean. Ex vivo biodistribution at 48 hours was assessed by gamma counting to evaluate radiotracer specificity and retention. Tumors were harvested for immunofluorescence (IF) analysis of human CD68 expression.\nResults: At 2 hours p.i., quantitative analysis of [89Zr]Zr-DFO-Fab14 uptake was similar in both humanized and control tumors, indicating comparable early distribution. By 24 hours, uptake of the immunoPET tracer was significantly higher and more sustained in humanized NSG-SGM3 mice (SUVmean = 0.29 ± 0.04) compared to control mice (SUVmean = 0.20 ± 0.03; ***p =0.0002). Biodistribution studies at 48 hours further validated the imaging specificity, showing markedly higher tumor retention in humanized NSG-SGM3 (4.66± 1.61 %ID/g) than in control NSG-SGM3 mice (1.71 ± 0.63 %ID/g). IF analysis confirmed abundant human CD68⁺ macrophage infiltration in humanized NSG-SGM3 tumors but not in NSG-SGM3 tumors, confirming the specificity of [89Zr]Zr-DFO-Fab14 for human macrophages.\nConclusions: The human-specific [89Zr]Zr-DFO-Fab14 demonstrates macrophage-specific retention in humanized tumors, enabling noninvasive visualization of human TAMs in vivo. This radiotracer represents a promising tool for studying macrophage dynamics in human immune-reconstituted systems and evaluating efficacy of macrophage-targeted therapies in cancer.", "source_company": "University of Alabama at Birmingham", "source_org_type": "大学", "row_number": 638, "target_meta": "CD68", "MOA_meta": "其他"}, {"drug_name": "MAP4K4 inhibitor", "company": "Princess Margaret Cancer Centre, University Health Network", "org_type": "医院", "target": "MAP4K4", "modality": "inhibitor", "importance_level": "低", "total_score": 49.5, "institution_score": 35, "track_score": 65, "milestone_score": 55, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "药物为MAP4K4抑制剂，通过破坏胶质母细胞瘤侵袭相关的焦点粘附和细胞骨架重塑，诱导协同致死脆弱性。机构为医院研究型，preclinical阶段以体外和类器官模型为主，靶点在肿瘤侵袭中有一定研究但非热门赛道，综合热度一般导致总分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6167", "id": "_lXM_5wBX1NQZOEH-LK6", "source_drug_name": "MAP4K4 inhibitor", "title": "Exploiting mechanisms of glioblastoma invasion to induce vulnerabilities that promote synergistic lethality", "abstract_text": "Glioblastoma (GBM) is the most common and aggressive form of adult brain cancer. Diffuse infiltration of tumor cells into surrounding vital brain tissue prevents complete surgical removal and poses a significant challenge to treatment. Therefore, a better understanding of the molecular programs that drive GBM invasion is crucial to designing more effective therapies. We hypothesized that GBM invasion is mediated by generalizable molecular mechanisms and that disrupting these programs induced vulnerabilities that could be exploited by combination therapies. In this study, we used a clinically diverse cohort of 17 patient-derived GBM cell lines and advanced experimental conditions to develop more controlled models of GBM invasion. Since hypoxia is a known driver of tumor invasion, we cultured GBM cells under 20%, 1%, and 0.2% oxygen concentrations and performed mass spectrometry-based profiling to investigate the invasive signaling pathways promoted by hypoxia. Additionally, we also performed mass spectrometry-based profiling of GBM cells cultured in the glioma cerebral organoid (GLICO) model of brain infiltration to investigate hypoxia-independent invasion mechanisms. These analyses identified the enrichment of several integrin-related signaling signatures as a general mediator of GBM invasion across cell lines, in both hypoxia-induced invasion conditions and in brain infiltration. To identify downstream targets of the integrin signaling pathway that could impair tumor cell migration, we performed a chemical screen using a MAPK compound library (n=802 compounds), which identified MAP4K4 as a top invasion-specific kinase. Pharmacological inhibition of MAP4K4 significantly impaired migration across multiple cell lines in live imaging experiments and reduced tumor infiltration in GLICOs, supporting its broad generalizability as a target to disrupt GBM invasion. By performing phospho-proteomic profiling, we then mechanistically determined that MAP4K4 inhibition led to the dysregulation of focal adhesion dynamics and cytoskeletal remodeling, which was validated through live fluorescent imaging experiments. Lastly, to explore if MAP4K4 inhibition induced vulnerabilities that could be exploited by sequential treatment with a second compound, we performed a combination screen using an FDA approved drug library (n=3196 compounds). We identified three compounds with a synergistic effect dependent on MAP4K4 inhibition that reduced tumor cell viability by 35-40% compared to single agent treatment. As the therapeutic strategies to treat GBM have remained unchanged for decades, the administration of synergistic drug combinations that exploit the characteristic infiltrative nature of GBM may therefore represent a promising treatment avenue for this devastating disease.", "source_company": "Princess Margaret Cancer Centre, University Health Network", "source_org_type": "医院", "row_number": 653, "target_meta": "MAP4K4", "MOA_meta": "抑制剂"}, {"drug_name": "anti-PD-1", "company": "University of Texas MD Anderson Cancer Center", "org_type": "医院", "target": "PD-1", "modality": "inhibitor", "importance_level": "低", "total_score": 49.5, "institution_score": 45, "track_score": 75, "milestone_score": 35, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "anti-PD-1为经典PD-1抑制剂，靶点成熟但非新药；MD Anderson医院/学术机构主导的机制探索研究，preclinical水平仅显示运动缓解血管毒性，无药物开发里程碑。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9693", "id": "E1XM_5wBX1NQZOEH-LO6", "source_drug_name": "anti-PD-1", "title": "Exercise attenuates anti-PD-1-induced adventitial macrophage inflammation in the aorta of aged melanoma-bearing mice", "abstract_text": "Immune checkpoint inhibitors (ICI) improve cancer outcomes but can induce vascular toxicity, potentially threatening long-term survivorship. In our pilot data using young male mice with tumors, anti-PD-1 increased vimentin, an endothelial-to-mesenchymal transition (EndMT) marker linked to early atherosclerosis, in laminar-flow regions of the aorta, and exercise attenuated this response. Given the rapid growth of our melanoma model and the greater vulnerability of aged mice to ICI-associated vascular injury, we used aged mice to capture early vascular responses and determine whether exercise modifies anti-PD-1-induced vascular inflammation. One-year-old female C57BL/6J mice were injected subcutaneously with BP melanoma cells. Once tumors became measurable, mice were assigned to three treatment groups: control IgG (N=12), anti-PD-1 (aPD-1, 150 μg × 5 doses = 750 μg total; N=9), or anti-PD-1 plus moderate treadmill exercise (aPD1+Ex, N=8) for two weeks. Tumor growth was monitored every other day. Thoracic aortas were collected, embedded as FFPE tissue microarrays, and scanned by multiplex immunofluorescence, and analyzed in Visiopharm for tissue segmentation (intima, media, adventitia), cell identification, and immune/vascular phenotyping. Exercise plus aPD-1 suppressed tumor growth significantly better than aPD-1 alone (~60% reduction vs. IgG; p = 0.04). Across cross-sectioned aortic rings containing ~706 total cells on average (19,069 cells across 29 vessels), whole-vessel counts of CD4+, CD8+, and B220+ cells were uniformly low across groups. B220+ cells showed a polarized pattern in the aPD-1 group, with elevated counts in only a subset of mice. In contrast, aPD-1 increased adventitial F4/80⁺ macrophages more than 2.5-fold relative to IgG (N.S.), consistent with early adventitial-driven vascular inflammation. Importantly, exercise significantly reduced adventitial infiltration accumulation (p=0.03). Additional spatial analyses of vascular inflammation and immune-vascular interactions are ongoing. In aged tumor-bearing mice, anti-PD-1 induces early aortic vascular toxicity characterized by adventitial macrophage inflammation, paralleling early inflammatory patterns reported in early human large-vessel vasculitis associated with ICI therapy. Exercise markedly attenuates this adventitial macrophage-driven vascular response without compromising antitumor efficacy, suggesting its potential as a non-pharmacologic strategy to mitigate early ICI-associated vascular injury.", "source_company": "University of Texas MD Anderson Cancer Center", "source_org_type": "医院", "row_number": 663, "target_meta": "PD1", "MOA_meta": "抑制剂"}, {"drug_name": "anti-PD-L1", "company": "University of Chicago", "org_type": "大学", "target": "PD-L1", "modality": "inhibitor", "importance_level": "低", "total_score": 49.5, "institution_score": 45, "track_score": 75, "milestone_score": 30, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "该记录针对anti-PD-L1抗体，但研究核心为FGFR3激活导致的免疫微环境机制及对PD-1/PD-L1阻断疗效的抵抗，非新药或特定药物开发；大学机构基础研究性质，preclinical机制探讨无明确里程碑进展。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5288", "id": "YlXM_5wBX1NQZOEH-LO6", "source_drug_name": "anti-PD-L1", "title": "FGFR3 impairs DC1s/CD8+ T cell clustering in bladder cancer preventing the PD-1/PD-L1 blockade-induced CD8+ T cell phenotypes associated with immunotherapy efficacy", "abstract_text": "Background: Despite advances in immunotherapy, median survival for advanced bladder cancer remains under 3 years, and mechanisms governing PD-1/PD-L1 blockade efficacy remain ill defined. Activation of fibroblast growth factor receptor-3 (FGFR3) has been shown to be linked to a non-T cell-inflamed tumor microenvironment (TME) and with resistance to checkpoint blockade. Using human bladder tumors and murine models, we investigated mediators of immunotherapy response and how FGFR3 shapes the immune landscape affecting PD-1/PD-L1 treatment efficacy.\nMethods: Multiplex immunofluorescence (mIF) and RNAscope were performed on 47 human bladder tumors to assess immune infiltrates and FGFR3 expression. A second cohort of 21 bladder tumors collected before anti-PD-1/PD-L1 therapy was analyzed by mIF and spatial transcriptomics (ST). CD8+ T cell and DC1 clustering was evaluated using an unbiased computational analysis (K-cross, a modified Ripley’s K function). ST was used to investigate the effect of FGFR3 expression on immune cells spatial distribution and transcripts. In vivo, subcutaneous and orthotopic MB49 models expressing FGFR3 G370C activating mutation, FGFR3 kinase-dead mutant (K508M), or control vector were used with/without anti-PD-L1. FTY720 was used to assess the requirement for new T cell entry into the TME for anti-PD-L1 efficacy. Tumor growth and immune phenotypes were analyzed by spectral flow cytometry.\nResults: FGFR3-activated tumors showed reduced CD86+ DC1s in tumor-draining lymph nodes (tdLN), impaired CD8+ T cell activation, greater exhaustion, and fewer TCF-1+ progenitor-exhausted CD8+ T cell (TPE) in the TME after anti-PD-L1 treatment. Blockade of new T cell entry to the TME abrogated the anti-PD-L1-induced accumulation of TPE in control tumors. FGFR3-kinase-dead mutation resulted in higher TPE frequencies in tumors, tdLN, and spleen, and reduced CD8+ T cell exhaustion. In human tumors, clinical response to PD-1/PD-L1 blockade was associated with CD8+/DC1 clustering rather than absolute cell numbers. FGFR3 expression inversely correlated with CD8+ and DC1 abundance and co-localization. Within tumors, FGFR3+ regions showed fewer DC1s, CD8+ T cells, reduced co-localization, and diminished expression of chemokines that recruit these cells. CD8+ T cells in FGFR3+ areas exhibited lower activation/effector and TPE gene expression and higher exhaustion/inhibitory-related transcripts, compared to those in FGFR3 negative areas.\nConclusions: Our results indicate that DC1/CD8+ T cell clustering is essential for PD-1/PD-L1 efficacy in bladder cancer, and FGFR3 activation drives resistance by disrupting this interaction, preventing CD8+ T cells from acquiring phenotypes required for effective immunotherapy.", "source_company": "University of Chicago", "source_org_type": "大学", "row_number": 716, "target_meta": "PDL1", "MOA_meta": "抑制剂"}, {"drug_name": "PD-L1 blockade", "company": "Fred Hutchinson Cancer Center", "org_type": "研究机构", "target": "PD-L1", "modality": "inhibitor", "importance_level": "低", "total_score": 49.5, "institution_score": 35, "track_score": 80, "milestone_score": 40, "field_heat_score": 75, "bonus_score": 0, "brief_reason": "PD-L1 blockade为经典免疫检查点抑制机制，赛道仍具较高热度，但本条摘要聚焦TCR-T细胞疗法在肿瘤引流淋巴结的DC竞争机制研究，非药物自身开发。研究机构+基础机制探讨导致总体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5156", "id": "Y1XM_5wBX1NQZOEH-LO6", "source_drug_name": "PD-L1 blockade", "title": "Competition for dendritic cells limits engineered TCR-T cell activation in tumor-draining lymph nodes and impairs synergy with PD-L1 blockade", "abstract_text": "Adoptive cell therapy with engineered T cells (i.e. CAR-T and TCR-T) has transformed outcomes for patients with hematologic malignancies, but their efficacy in solid tumors remains limited. To improve responses, these therapies are increasingly combined with PD-1/PD-L1 blockade, though results remain variable. For endogenous T cells, PD-1/PD-L1 blockade expands PD-1⁺Tcf1⁺ progenitor exhausted T cells (Tpex) in tumor-draining lymph nodes (TdLNs), where dendritic cells (DCs) maintain them through antigen presentation. However, it is unclear whether engineered T cells form an analogous Tpex reservoir in TdLNs that can replenish effector T cells in tumors and respond to PD-1/PD-L1 blockade.\nTo test this, we used the Kras/p53 model of lung cancer expressing ovalbumin (KPOva) to compare endogenous and engineered TCR-T cells targeting the same neoantigen. OT-I transgenic CD8 T cells were expanded in vitro to generate Ova-specific engineered TCR-T cells, and Ova-specific endogenous T cells (Endog-T) were identified with a pMHC tetramer.\nConsistent with prior reports, Endog-T in untreated KPOva mice accumulated in TdLNs and adopted a PD-1⁺Tcf1⁺ Tpex phenotype. In contrast, in mice treated with cyclophosphamide (Cy) lymphodepletion and infusion of 1x10⁶ TCR-T cells, TCR-T also accumulated in TdLNs, but they displayed significantly reduced PD-1 expression compared to Endog-T. Despite lower PD-1 levels, TCR-T cells in TdLNs produced less IL-2 and exhibited impaired tumor control relative to Endog-T, indicating they adopted a hypofunctional state. Further, while PD-L1 blockade improved anti-tumor immunity in untreated mice, it drove terminal differentiation of TCR-T in tumors and failed to enhance TCR-T-mediated tumor control.\nMechanistically, lymphodepletion reduced TdLN DC numbers by ~70%, increasing the TCR-T:DC ratio from ~1:1 to ~200:1. Imaging revealed large swarms of TCR-T cells competing for contact with limited numbers of DCs in TdLNs. However, doubling DC numbers in TdLNs with anti-CD40 and Flt3L vaccination was insufficient to overcome this imbalance and failed to increase TCR-T activation. In contrast, infusing 100-fold fewer TCR-T (1x104) significantly reduced the TCR-T:DC ratio to ~9:1, which restored TCR-T PD-1 expression, IL-2 production, and expansion capacity. Importantly, this reduced competition in TdLNs enabled TCR-T cells to respond to PD-L1 blockade, resulting in improved tumor control.\nOur data suggest that Cy lymphodepletion and high-dose TCR-T induces competition for DCs in TdLNs, which limits their activation, function, and synergy with PD-L1 blockade. Thus, strategies that reduce competition here may promote Tpex formation and sensitize TCR-T therapy to PD-L1 blockade­­—and potentially vaccination—to improve control of solid tumors.", "source_company": "Fred Hutchinson Cancer Center", "source_org_type": "研究机构", "row_number": 717, "target_meta": "PDL1", "MOA_meta": "抑制剂"}, {"drug_name": "anti-PD-L1", "company": "Massachusettes General Hospital", "org_type": "医院", "target": "PD-L1", "modality": "inhibitor", "importance_level": "低", "total_score": 49.5, "institution_score": 35, "track_score": 75, "milestone_score": 45, "field_heat_score": 65, "bonus_score": 0, "brief_reason": "anti-PD-L1为经典免疫检查点抑制剂，与CD49b（integrin α2）联合可增强乳腺癌中CD8⁺ T细胞抗肿瘤效应，克服ECM介导的ICB耐药。机构为医院而非药企、仅为动物水平协同机制研究、无临床阶段进展导致总体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10545", "id": "c1XM_5wBX1NQZOEH-LO6", "source_drug_name": "anti-PD-L1", "title": "Targeting collagen receptor CD49b enhances PD-L1 blockade by promoting CD8⁺ T-cell immunity in breast cancer", "abstract_text": "Background: Immune checkpoints blockade (ICB) have improved cancer outcomes, but its efficacy in breast cancer remain limited by an immunosuppressive tumor microenvironment and dense extracellular matrix (ECM). Collagen, the main ECM component, supports tumor progression and immune evasion via integrin-mediated signaling and DDRs receptors. The collagen receptor CD49b (integrin α2) promotes tumor adhesion. This study evaluated whether CD49b targeting enhances PD-L1 blockade to overcome ECM-driven resistance.\nMethods: Expression of CD49b, CD29, and DDR1 were profiled in breast cancer cell lines by flow cytometry, along with MHC-I and PD-L1. Collagen adhesion assays followed CD49b inhibition using Vatelizumab (anti-human CD49b), HMα2 (anti-mouse CD49b), or CRISPR/Cas9 knockout in 4T1 cells. Transcriptomic datasets (CCLE, scRNA-seq, spatial transcriptomics) were analyzed to define collagen receptor localization in breast cancer TME. In vivo, 4T1-bearing mice were treated with anti-PD-L1, anti-CD49b, or the combination, followed by analysis of tumor growth and tumor immune infiltration.\nResults: CD49b and CD29 were highly expressed in MCF7, T47D, and 4T1 cells, while MDA-MB-231 cells showed low levels and weak collagen adhesion. CD49b blockade or knockout impaired adhesion and delayed tumor growth in vivo without affecting proliferation. Transcriptomic analysis confirmed CD49b enrichment in malignant cells. Dual CD49b and PD-L1 inhibition showed a synergistic antitumor activity, significantly reducing tumor burden and increasing CD8⁺ T-cell infiltration and IFN-γ expression, consistent with enhanced cytotoxic immunity.\nConclusions: CD49b mediates tumor-ECM interaction in breast cancer. Combined CD49b and PD-L1 blockade remodels the TME, enhances CD8⁺ T-cell-driven responses, and represents a promising therapeutic strategy to overcome ICB resistance in collagen enriched tumors.", "source_company": "Massachusettes General Hospital\nMassachusetts General Hospital", "source_org_type": "医院", "row_number": 727, "target_meta": "PDL1", "MOA_meta": "抑制剂"}, {"drug_name": "peptide-drug conjugate", "company": "Metrum Research Group", "org_type": "公司", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 49.5, "institution_score": 45, "track_score": 70, "milestone_score": 30, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "该条目为peptide-drug conjugate（PDC）的平台PBPK-QSP建模研究，优化肽分子量以改善肿瘤暴露，未披露具体靶点或药物实体。Metrum为建模咨询公司而非药物研发机构，得分较低；虽PDC赛道有一定热度，但仅为方法学工具研究，无具体里程碑进展。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3380", "id": "e1XM_5wBX1NQZOEH-LO6", "source_drug_name": "peptide-drug conjugate", "title": "Using physiologically-based pharmacokinetics-quantitative systems pharmacology model to optimize peptide-drug conjugates design", "abstract_text": "Introduction: Peptide-drug conjugates (PDCs) are being developed as new cancer treatments. Compared to larger antibody-drug conjugates (ADCs), they retain the advantage of a targeted therapy, binding to tumor-associated antigens (TAA) to deliver payload, while having better tumor penetration than ADCs. PDCs typically exhibit faster plasma clearance than ADCs, and therefore potentially have less tumor exposure to the drug. The pharmacokinetics is influenced by the molecular weight (MW) of the peptide used in the PDC. A physiologically-based pharmacokinetics (PBPK)-quantitative systems pharmacology (QSP) model would be useful to understand the interplay of pharmacokinetics (PK), tissue disposition, and tumor drug exposure of PDCs.\nMethods: A platform PBPK-QSP model was developed based on a published PBPK model (Li et al., 2019) and a genetic tumor QSP model (Scheuher et al., 2024) by coupling these two models with a MW-based tumor penetration relationship. Through calibrated model simulations and sensitivity analysis, we interrogate how parameters of the peptide (e.g., molecular weight, binding affinity towards TAA) impact the PK, tissue disposition, and tumor drug exposure.\nResults: The model predicted higher tumoral PDC concentration when the peptide was small, corresponding to the knowledge that smaller peptides resulted in better tumor penetration. However, a bell-shaped relationship was predicted between peptide size and PDC or payload exposure. The model predicts that a peptide with MW of approximately 86 kDa results in maximum tumor PDC or payload exposure despite exhibiting more rapid PK clearance than a 150 kDa ADC. This is in contrast with tissue disposition, as larger peptides led to higher non-tumoral tissue exposure. Further sensitivity analysis indicated this relationship is insensitive to tumor characteristics, such as TAA expression, or PDC binding affinity towards the TAA, but is sensitive to the peptide size.\nConclusions: This work demonstrated that this platform PBPK-QSP model can be a useful tool to guide PDC design and lead selection by optimizing peptide size for PDCs.", "source_company": "Metrum Research Group", "source_org_type": "公司", "row_number": 732, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "anti-CTLA4 antibody", "company": "UC Irvine", "org_type": "大学", "target": "CTLA4", "modality": "inhibitor", "importance_level": "低", "total_score": 49.5, "institution_score": 35, "track_score": 75, "milestone_score": 40, "field_heat_score": 65, "bonus_score": 0, "brief_reason": "药品为anti-CTLA4抗体（CTLA4抑制剂），属于经典免疫检查点抑制剂，赛道仍具一定热度，但摘要仅展示小鼠模型中与达比加群酯联合的协同作用，未见临床阶段数据。大学机构研发且仅为preclinical研究，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6765", "id": "hFXM_5wBX1NQZOEH-LO6", "source_drug_name": "anti-CTLA4 antibody", "title": "Dabigatran etexilate potentiates the anti-tumor effects of anti-CTLA4 antibody through remodeling the immune microenvironment in a syngeneic mouse model of MyC-CaP cells", "abstract_text": "Dabigatran etexilate, an FDA approved thrombin inhibitor, has been used for treatment of venous thromboembolism for many years in cancer patients, including prostate cancer patients. Beyond its anticoagulant properties, the anti-prostate cancer properties and immunomodulatory capacity of dabigatran etexilate remain largely uncharacterized. Therefore, this study aims to determine the anti-tumor effects of dabigatran etexilate alone and its combination with anti-CTLA4 antibody in a syngeneic mouse model of MyC-CaP cells. Mice bearing MyC-CaP xenograft tumors received dabigatran etexilate daily via oral gavage and/or anti-CTLA4 antibody treatments every other day through intraperitoneal injection for 14 days. Tumor volumes were monitored throughout the treatments, after which fresh tumor tissues were dissected for flow cytometric characterization of tumor-infiltrating lymphocytes (TILs). The combination of dabigatran etexilate and murine anti-CTLA4 blocking antibody resulted in significantly enhanced anti-tumor efficacy, achieving 18% greater tumor growth inhibition compared to anti-CTLA4 monotherapy alone, and markedly prolonged overall survival of tumor bearing mice. Flow cytometry analysis revealed that dabigatran etexilate in combination with anti-CTLA4 antibody significantly increased effector T cell (Teff) populations while reducing regulatory T cells (Tregs). Notably, granzyme B-positive cytotoxic CD8+ T cells increased by 1.6 folds in the combination group compared to anti-CTLA4 monotherapy. In addition, granulocytic myeloid-derived suppressor cells (Gr-MDSCs) were significantly reduced in the combination group. Furthermore, single-cell analysis of tumor-infiltrating lymphocytes revealed that dabigatran etexilate and anti-CTLA4 combination therapy markedly increased cytotoxic natural killer (NK) cell infiltration while decreasing suppressive and exhausted NK cell populations. Taken together, our data has shown that dabigatran etexilate potentiates anti-CTLA4 therapy by activating cytotoxic T and NK cells while suppressing immunosuppressive Tregs and Gr-MDSCs. These results suggest that dabigatran etexilate deserves further investigation as a new immunomodulatory agent for prostate cancer prevention and treatment.", "source_company": "UC Irvine", "source_org_type": "大学", "row_number": 739, "target_meta": "CTLA4", "MOA_meta": "抑制剂"}, {"drug_name": "SMIR-181s", "company": "University of Michigan", "org_type": "大学", "target": "miR-181a", "modality": "inhibitor", "importance_level": "低", "total_score": 49.5, "institution_score": 35, "track_score": 75, "milestone_score": 45, "field_heat_score": 65, "bonus_score": 3, "brief_reason": "SMIR-181s为小分子抑制miR-181a加工过程，通过诱导TARBP2降解阻断miR-181a成熟，机制新颖但仍处早期发现阶段。大学机构+preclinical初步验证导致总体分较低，创新小核酸相关赛道有一定热度但未达临床里程碑。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4682", "id": "n1XM_5wBX1NQZOEH-LO6", "source_drug_name": "SMIR-181s", "title": "Therapeutic inhibition of oncogenic miR-181a processing for cancer therapy", "abstract_text": "Background: Oncogenic microRNA-181a (miR-181a) is a master regulator of tumor pathogenesis, driving cancer initiation, progression, metastasis, and immune evasion across diverse cancer lineages by suppressing critical pathways such as STING, WNT, and TGFβ signaling. While genetic ablation of miR-181a is potently anti-tumorigenic and well tolerated, no therapies currently exist targeting miR-181a, presenting a critical therapeutic gap. Targeting miR-181a offers a promising strategy as it regulates multiple oncogenic pathways simultaneously, unlike existing therapies that act on a single target. Nucleotide-based miRNA-targeting therapies have made significant advances with more than 1,300 clinical trials having been conducted to target miRNAs; yet challenges remain in bioavailability, stability, and effective delivery. Therefore, a small molecule pharmacological strategy targeting miR-181a processing represents an attractive alternative with superior pharmacokinetic properties, improved stability, and enhanced delivery potential. Here, we report the discovery and characterization of SMIR-181s (Small Molecule Inhibitors of miR-181a), a novel class of compounds that alter miR-181a biogenesis and suppress cancer properties.\nResults: Using a high-throughput biosensor-based screening platform in miR-181a dependent cancer lines, we identified a novel small molecule inhibitor of miR-181a biogenesis. Screening identified a class of seven SMIR-181s, that impair miR-181a maturation, resulting in the accumulation of precursor miR-181a accumulation and depletion of mature. Mechanistic studies reveal that SMIR-181s mediate this depletion by inducing degradation of TARBP2 (Trans-Activating Responsive Binding Protein 2), an RNA-binding protein that acts as a rheostat for stress-induced miRNAs such as miR-181a. Importantly, SMIR-181s display broad cytotoxicity across the NCI-60 cancer cell line panel, with enhanced efficacy in miR-181a high tumor cells while sparing normal cells. Furthermore, these compounds trigger apoptosis and exhibit a novel mechanism of action distinct from all known agents in the NCI-60 database.\nConclusions: Collectively, this work emphasizes miR-181a’s potential as a predictive biomarker, establishes proof-of-concept for small molecules that target miRNA processing, and nominates the SMIR-181 class as first-in-class candidates for the treatment of a broad spectrum of miR-181a-driven malignancies.", "source_company": "University of Michigan", "source_org_type": "大学", "row_number": 756, "target_meta": "miR-181a", "MOA_meta": "抑制剂"}, {"drug_name": "IDH1 inhibitors", "company": "Columbia University", "org_type": "大学", "target": "IDH1", "modality": "inhibitor", "importance_level": "低", "total_score": 49.5, "institution_score": 30, "track_score": 75, "milestone_score": 55, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "该研究聚焦IDH1抑制剂在新机制组合策略中针对IDH突变胶质瘤的细胞状态特异性敏感性，但未披露具体新类药物细节，仅为概念验证。大学机构非核心药企导致机构分较低，preclinical探索阶段里程碑有限，总分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3661", "id": "olXM_5wBX1NQZOEH-LO6", "source_drug_name": "IDH1 inhibitors", "title": "High-throughput drug screening and single-cell network analysis identify rational combination therapies in IDH-mutant glioma", "abstract_text": "IDH-mutant gliomas are lethal brain tumors marked by multiple coexisting malignant cell states, likely to elicit heterogeneous drug sensitivities thus limiting the effectiveness of monotherapy. To address this challenge, we integrated multimodal single-cell analysis and functional high-throughput drug screening to identify and pharmacologically target state-specific vulnerabilities, thus supporting rational combination therapy development. Single-nucleus RNA sequencing (snRNA-seq) of 20 treatment-naïve, low-grade IDH-mutant gliomas, followed by Master Regulator (MR) analysis, identified key proteins representing mechanistic determinants of three established malignant states: astrocyte-like (AC), oligodendrocyte-like (OC), and neural progenitor cell-like (NPC). The analysis revealed that the AC state is transcriptionally orthogonal to OC, whereas the OC and NPC share substantial regulatory architecture. OncoMatch analysis identified patient-derived models (SF10417, SU-A03) that optimally recapitulate the MRs of these malignant subpopulations, supporting screening of a 374 oncology-focused compounds (FDA-approved and investigational) followed by transcriptional profile analysis at 24h, using the PLATE-seq technology, resulting in a comprehensive drug perturbational compendium for IDH-mutant gliomas. OncoTreat analysis prioritized compounds based on their ability to invert the aberrant MR activity signatures of each malignant state, revealing highly cell-state-specific drug sensitivities, supporting the design of rational combination strategies targeting tumor plasticity. For example, we found that AC-like cells may first be primed with the mTOR inhibitor temsirolimus to reprogram them toward a more drug-sensitive OC-like state, thereby converting a resistant lineage into one that is more vulnerable, including to the new class of IDH1 inhibitors. A second-line agent such as the HDAC inhibitor romidepsin or the topoisomerase inhibitor irinotecan can then be used, possibly in combination with IDH1 inhibitors, to target the resulting OC-like and pre-existing OC/NPC cells, thus implementing a two-step, sequential treatment strategy. In parallel, barcode-based lineage tracing in SF10417 and SU-A03 is being used to monitor cell-state stability and plasticity under drug treatment, while top candidate agents and combinations are being validated in patient-derived ex vivo glioma slice cultures that preserve the native microenvironment. Single-cell and spatial transcriptomic profiling (10x Genomics Xenium) of treated slices will map the reprogramming and elimination of malignant subpopulations in situ. Together, this framework provides a blueprint for discovering state-specific dependencies in IDH-mutant glioma and for guiding rational, combination-based strategies to overcome intratumoral heterogeneity.", "source_company": "Columbia University", "source_org_type": "大学", "row_number": 759, "target_meta": "IDH1", "MOA_meta": "抑制剂"}, {"drug_name": "diABZI", "company": "University of Kansas Medical Center", "org_type": "大学", "target": "STING", "modality": "agonist", "importance_level": "低", "total_score": 49.5, "institution_score": 30, "track_score": 85, "milestone_score": 40, "field_heat_score": 80, "bonus_score": 0, "brief_reason": "diABZI为非核苷酸类合成STING激动剂，用于激活肿瘤内STING通路增强抗肿瘤免疫；大学机构preclinical体外研究，opaganib联合增效但无独立开发里程碑，赛道热门但机构非商业化实体导致总分较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5673", "id": "yFXM_5wBX1NQZOEH-LO6", "source_drug_name": "diABZI", "title": "The SPHK2 inhibitor opaganib potentiates tumor-intrinsic STING activation in triple-negative breast cancer in vitro", "abstract_text": "Triple-negative breast cancer (TNBC) has the poorest prognosis of breast cancer subtypes. Patients with TNBCs that exhibit robust stromal tumor infiltrating lymphocytes and/or gene expression signatures indicative of immune activation have improved response rates to chemotherapy and immunotherapy. DNA damage induces anti-tumor immunity through the stimulator of interferon genes (STING) protein pathway, and STING activation has been associated with better response rates and improved prognosis in TNBC. However, TNBCs also have elevated levels of sphingosine-1-phosphate (S1P), an immunomodulatory biolipid with pleiotropic effects. S1P is produced by sphingosine kinase 1 (SPHK1) and sphingosine kinase 2 (SPHK2). SPHK1 has been shown to lead to cancer cell progression and metastasis, while the role of SPHK2 in TNBC is less well-studied. SPHK2-dependent S1P production has been shown to inhibit STING in an acute lung injury model. Whether tumor-intrinsic STING is inhibited by the SPHK2-S1P axis is not known. We hypothesized that SPHK2 modulates STING pathway activity, and that SPHK2-dependent S1P biogenesis could be targeted to augment anti-tumor immunity in TNBC. We evaluated opaganib, an SPHK2 small molecule inhibitor with FDA orphan drug designation, in in vitro TNBC models (BT-549, HCC70, MDA-MB-231, and MDA-MB-468). Opaganib alone did not increase STING activation. However, pre-treatment with opaganib potentiated the synthetic STING agonist diABZI in all cell models. Compared to diABZI alone, western blots of cells treated with the opaganib-diABZI combination had enhanced phosphorylation of STING pathway proteins, such as STING, IRF3, and TBK1. Using BT-549 cells with an interferon stimulated response element (ISRE) luciferase reporter system, we analyzed transcriptional activity downstream of the STING pathway and found that ISRE activity increased in a dose-dependent manner with diABZI-mediated STING stimulation. However, pre-treatment of BT-549 cells with exogenous S1P decreased the diABZI-mediated ISRE activity. Conversely, pre-treatment with opaganib followed by low-dose diABZI treatment potentiated the downstream STING-mediated effects. To further analyze cellular responses to SPHK2 inhibition and STING agonism, we evaluated mRNA expression of 770 immuno-oncology-related genes (NanoString PanCancer IO 360 panel for nCounter) in drug-treated cells. Upregulated pathways in cells treated with the opaganib-diABZI combination compared to cells treated with diABZI alone or opaganib alone included cytokine signaling in immune system and responses to cytokine stimulus. In summary, we show that malignancy-associated production of S1P blunts tumor-intrinsic STING activity and suggest that targeting the SPHK2-S1P axis with opaganib may augment anti-tumor immunity in TNBC.", "source_company": "University of Kansas Medical Center", "source_org_type": "大学", "row_number": 790, "target_meta": "STING", "MOA_meta": "激动剂"}, {"drug_name": "anti-PD1 antibody", "company": "UTHSA", "org_type": "大学", "target": "PD-1", "modality": "inhibitor", "importance_level": "低", "total_score": 49.5, "institution_score": 30, "track_score": 75, "milestone_score": 45, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "药品为anti-PD1抗体，靶点PD-1为经典免疫检查点靶点，赛道仍具一定热度；但研究来自大学机构，在已成熟的anti-PD1药物基础上仅于特定小鼠模型中验证响应，缺乏新机制或临床开发价值。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5582", "id": "ylXM_5wBX1NQZOEH-LO6", "source_drug_name": "anti-PD1 antibody", "title": "Co-activation of Wnt/β-catenin and c-MET induced inflamed hepatocellular carcinoma responsive to immune checkpoint therapy", "abstract_text": "Hepatocellular carcinoma (HCC), the major form of liver cancer, is often detected at advanced and unresectable stages, making it one of the deadliest cancers in adults. The front-line treatment for unresectable advanced HCC involves immune checkpoint therapy (ICT), which shows complete response only in 20-30% of patients. Mutational activation of Wnt/β-catenin pathway due to gain-of-function mutations in β-catenin gene (CTNNB1) is a major oncogenic event driving hepatocarcinogenesis accounting for about a third of HCC. However, oncogenic forms of β-catenin often cooperate with other oncogenes like c-MET, K-RAS, and AKT for tumor development and progression. For instance, activated β-catenin in HCC can induce the expression of c-MYC, which facilitates metabolic adaptation of HCC cells and tumor associated macrophages (TAMs). Several clinical and preclinical studies have shown that HCC tumors with CTNNB1 mutation are often less inflamed with limited immune cell infiltration making the tumors “immune-cold” and resistant to ICT. On the other hand, mutational activation of the Wnt/β-catenin also occurs in “immune-hot” HCC tumors suggesting that the tumor immune microenvironment (TIME) is co-regulated by other oncogenic events. Although, murine HCC tumors generated by hydrodynamic co-transfection of ΔN90-β-cat (a constitutively active β-catenin) and c-MYC are “immune-cold”, the events that cooperate with β-catenin activation leading to “immune-hot” tumors are unknown. In this study, we used hydrodynamic tail vein injection (HTVI) of plasmids expressing ΔN90-β-cat and c-MET to investigate their effect on HCC development, progression, and TIME. Immune-profiling of our ΔN90-β-cat and c-MET tumor model showed increased infiltration of PD-1+ cytotoxic T cells and Th1 cells, both of which are crucial for anti-tumor response. Although T cells were present in the tumor microenvironment, the upregulation of PD-1 indicates an exhausted state of T cells, permitting HCC progression. Therefore, we hypothesized that checkpoint blockade reactivates the exhausted T cells leading to better anti-tumor response. Accordingly, HTVI generated HCC bearing FVB/NJ male mice treated with anti-PD1 antibody showed significant tumor regression/stabilization compared to those treated with isotype control antibody, as indicated by lower levels of plasma alpha-fetoprotein (AFP), a biomarker of HCC, along the treatment course as well as the terminal tumor size. Additionally, immune profiling of the anti-PD1 treated tumors show significantly elevated population of total and resident cytotoxic T cells compared to the isotype control group. Therefore, HCC tumors formed by combination of ΔN90-β-cat and c-MET are “immune-hot” and respond to ICT. These findings further indicate that, co-activation of c-MET and β-catenin could serve as biomarkers for HCC patient inclusion in ICT.", "source_company": "UTHSA", "source_org_type": "大学", "row_number": 793, "target_meta": "PD1", "MOA_meta": "抑制剂"}, {"drug_name": "PD-1 antibody", "company": "GenoBioTX LLC", "org_type": "公司", "target": "PD-1", "modality": "inhibitor", "importance_level": "低", "total_score": 49.5, "institution_score": 45, "track_score": 85, "milestone_score": 30, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "药品为PD-1抗体（checkpoint inhibitor），靶点PD-1在免疫治疗领域热度高，但摘要中仅作为对照/联合用药工具在新型小鼠模型中验证，未体现药物自身开发进展。GenoBioTX为专注动物模型和CRO服务的中小型biotech，非头部药企，导致机构分较低，整体仅preclinical工具性研究。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1421", "id": "5VXM_5wBX1NQZOEH-LO6", "source_drug_name": "PD-1 antibody", "title": "A novel syngeneic model for evaluating the efficacy of MYC-driven liver cancer targeted and immunotherapy", "abstract_text": "In liver cancer, MYC and its signaling pathways undergo significant changes, exerting a profound impact on liver cancer progression. These effects include tumor proliferation, metastasis, dedifferentiation, metabolism, immune microenvironment, and resistance to comprehensive therapies. This makes MYC a highly attractive therapeutic target.Our laboratory engineered mice on a C57BL/6 background with hepatocyte-specific expression of mouse c-Myc, resulting in rapid, spontaneous hepatocellular carcinoma (abbr. c-Myc/ALB model). Primary tumors were harvested and cultured to establish a novel spontaneous tumor cell line. In the c-Myc/ALB syngenic tumor model of immunocompetent C57BL/6 mice, the c-Myc inhibitor 10058-F4 significantly inhibited tumor growth in a dose-dependent manner. The PD-1 antibody in combination of 10058-F4 and immune checkpoint inhibitor PD-1 antibody showed better anti-tumor efficiency.", "source_company": "GenoBioTX LLC", "source_org_type": "公司", "row_number": 812, "target_meta": "PD1", "MOA_meta": "抑制剂"}, {"drug_name": "UM4118", "company": "Johns Hopkins University", "org_type": "大学", "target": "未披露", "modality": "copper ionophore", "importance_level": "低", "total_score": 49.5, "institution_score": 30, "track_score": 85, "milestone_score": 40, "field_heat_score": 80, "bonus_score": 3, "brief_reason": "UM4118为铜离子载体，通过诱导cuproptosis机制在TP53突变AML中绕过p53依赖凋亡通路发挥作用。机构为大学非商业化研发，得分较低；赛道cuproptosis为新兴热门机制，但仍处preclinical阶段，整体重要性偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4612", "id": "KlXM_5wBX1NQZOEH-LS6", "source_drug_name": "UM4118", "title": "Cuproptosis induction in TP53-mutated acute myeloid leukemia", "abstract_text": "Patients with acute myeloid leukemia (AML) carrying TP53 loss-of-function mutations exhibit extremely poor outcomes, partly due to intrinsic resistance to current treatments such as intensive chemotherapy and venetoclax-based regimens that depend on p53-mediated apoptosis. Developing therapeutic strategies capable of bypassing defective apoptotic pathways and eliminating TP53-deficient AML remains a critical need. Copper ionophores, including elesclomol—a compound previously evaluated in clinical trials—and its next-generation analog UM4118, trigger a mitochondria-dependent, nonapoptotic mode of copper-regulated cell death known as cuproptosis. Here, we demonstrate that inducing cuproptosis through these agents effectively targets AML cells in a p53-independent manner.Analysis of the BEAT AML 2.0 dataset revealed that the copper ionophore elesclomol exhibits the strongest anti-leukemic activity in TP53-mutated AML cells compared with TP53 wild-type counterparts. Based on this observation, we hypothesized that cuproptosis induction could suppress AML cell growth and survival independent of p53 status. To test this, TP53 was disrupted via CRISPR-Cas9 gene editing in 3 TP53 wild-type human AML cell lines (MOLM13, MV4-11, and UKE-1) to generate isogenic TP53 knockout derivatives, along with UKE-1 clones harboring heterozygous and homozygous TP53 R273H mutations. Short-term viability and growth assays demonstrated a marked, dose-dependent reduction in viability 72 hours after treatment with copper ionophores, with comparable sensitivity across TP53 wild-type, TP53-KO, and TP53-deficient (TF-1 and F36P) AML cells. In contrast, cytarabine, idarubicin, and venetoclax activity was substantially diminished in TP53-deficient cells, consistent with the known resistance of TP53-mutated AML to these standard therapies. Notably, combining low-dose elesclomol with the hypomethylating agent decitabine, which has established clinical efficacy in TP53-mutated AML, produced a synergistic increase in apoptosis in TP53-deficient AML cells.Together, these findings demonstrate that copper ionophores can bypass TP53-associated resistance to AML cell death by activating cuproptosis rather than relying on p53-dependent apoptotic pathways. The robust activity of copper ionophores across diverse TP53-deficient AML models, coupled with the enhanced efficacy observed in combination with decitabine, underscores cuproptosis induction as a promising therapeutic approach for TP53-deficient AML.", "source_company": "Johns Hopkins University", "source_org_type": "大学", "row_number": 860, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "ELX19", "company": "University Hospital of Cologne", "org_type": "医院", "target": "SIX1", "modality": "PROTAC", "importance_level": "低", "total_score": 49.5, "institution_score": 30, "track_score": 85, "milestone_score": 40, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "ELX19为针对SIX1的首创PROTAC降解剂，SIX1在HNSCC中驱动EMT且正常组织低表达，具有潜在治疗价值；PROTAC赛道热门，但由医院机构开发、仅初步体外实验阶段，整体开发早期且非产业化主力。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5669", "id": "N1XM_5wBX1NQZOEH-LS6", "source_drug_name": "ELX19", "title": "Investigating SIX1 as a driver and target for a first in-class EMT degrader in head-and-neck squamous cell carcinoma", "abstract_text": "Prognosis for head-and-neck squamous cell carcinoma (HNSCC) remains poor in advanced stages, and patients suffer from severe treatment-associated adverse effects. Here, we have preliminarily investigated whether the embryonic transcription factor SIX1 drives HNSCC and could serve as a target for a first-in-class EMT degrader. While SIX1 is required during embryonic development, it is no longer or only weakly expressed in adult tissue. However, many cancers show a reactivation of SIX1, leading to various pro-tumorigenic effects such as an increase in proliferation and an induction of epithelial-mesenchymal transition (EMT). This makes SIX1, particularly combined with its absent or low expression in normal tissue, a potentially therapeutic target. For this purpose, we developed a SIX1-specific PROTAC (ELX19) through a CRO. In this project, we have applied sequential immunofluorescence for the analysis of patient tissue, and in vitro assays to test the efficiency of the SIX1 degradation through ELX19 and detect associated phenotypic effects. The 36-marker immunofluorescence panel confirmed an increased SIX1 expression in cancer tissue and showed a correlation between SIX1 and an immunosuppressive immune infiltrate, highlighting potential mechanistic links between SIX1 and HNSC progression. Regarding the PROTAC, ELX19 led to an efficient SIX1 degradation in the nanomolar and low micromolar range (depending on the cell line) and induced therapeutically desirable effects, such as an increase in apoptosis under cisplatin. In conclusion, these preliminary results indicate the potential of SIX1 as a therapeutic option in HNSCC - an option that patients urgently need.", "source_company": "University Hospital of Cologne", "source_org_type": "医院", "row_number": 871, "target_meta": "SIX1", "MOA_meta": "PROTAC"}, {"drug_name": "STAT3 inhibition", "company": "Ruijin Hospital Affiliated to Shanghai Jiao Tong University School of Medicine", "org_type": "医院", "target": "STAT3", "modality": "inhibitor", "importance_level": "低", "total_score": 49.5, "institution_score": 30, "track_score": 75, "milestone_score": 60, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "靶向STAT3抑制以协同KRAS抑制克服KRAS突变癌耐药，主要基于体外/体内实验及筛选，未披露具体STAT3抑制药物。医院机构非药企导致institution_score较低，赛道有一定热度但整体preclinical阶段及无明确临床里程碑使总分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5038", "id": "PlXM_5wBX1NQZOEH-LS6", "source_drug_name": "STAT3 inhibition", "title": "Targeting the JAK-STAT pathway sensitizes KRAS-mutant cancer to KRAS inhibitors", "abstract_text": "Targeting KRAS is promising in KRAS-mutant cancers. However, primary and acquired resistance to KRAS inhibitors impedes their clinical use. We conducted a Phase IIa clinical trial enrolling 7 patients with resectable PDAC bearing KRAS^G12D mutations, who received standard neoadjuvant chemotherapy plus KRAS inhibitors. Genomic analyses revealed acquired mutations in KRAS and other cancer-related. Single-cell transcriptomic profiling showed significant differences in cancer-associated fibroblast (CAF) populations between responders and non-responders. Kinome CRISPR library screening and FDA-approved compound library screening nominated the JAK-STAT pathway as critical for response to KRAS inhibition. Cell lines resistant to KRAS inhibitors have activated JAK-STAT pathway. In vitro and in vivo, STAT3 inhibition synergized with KRAS inhibition, altered cytokine secretion by cancer cells, and modulated CAF status. These findings demonstrate that activation of the JAK-STAT pathway is a common mechanism of resistance to KRAS inhibitors in diverse KRAS-mutant cancers and suggest that dual targeting of KRAS and STAT3 may enhance therapeutic efficacy.", "source_company": "Ruijin Hospital Affiliated to Shanghai Jiao Tong University School of Medicine", "source_org_type": "医院", "row_number": 875, "target_meta": "STAT3", "MOA_meta": "抑制剂"}, {"drug_name": "CAR-T cell therapy", "company": "Peking University First Hospital", "org_type": "医院", "target": "未披露", "modality": "CAR", "importance_level": "低", "total_score": 49.5, "institution_score": 35, "track_score": 85, "milestone_score": 30, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "该研究针对CD8+ CAR-T细胞，通过胱氨酸限制经GCN2-eIF2α-SLC1A5轴促进OXPHOS以增强CAR-T效力，但靶点未明确披露，仅为优化策略。机构为医院非主流药企、摘要仍保密处于preclinical基础研究阶段导致总分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11589", "id": "SFXM_5wBX1NQZOEH-LS6", "source_drug_name": "CAR-T cell therapy", "title": "Cystine restriction enhances CD8+ CAR-T potency by promoting OXPHOS via GCN2-eIF2α-SLC1A5 axis", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Peking University First Hospital", "source_org_type": "医院", "row_number": 882, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "T-cell therapy", "company": "Weill Cornell Medicine", "org_type": "大学", "target": "未披露", "modality": "CAR", "importance_level": "低", "total_score": 49.5, "institution_score": 40, "track_score": 85, "milestone_score": 30, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "摘要被禁运，未披露具体T细胞疗法靶点或机制，仅为DLBCL中T细胞疗法响应的表观遗传免疫排斥研究，来自大学机构。机构非商业公司得分为40；T细胞疗法赛道热门得高分，但仅preclinical模型研究且无具体药物里程碑，总体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11401", "id": "cp7ECZ0BZznHJdntvNYd", "source_drug_name": "T-cell therapy", "title": "Humanized PDX models uncover drug-reversible epigenetic immune exclusion governing T-cell therapy response in DLBCL, captured in patients by EPICORE stratifier", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Weill Cornell Medicine", "source_org_type": "大学", "row_number": 892, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "Gem-miR-15a", "company": "Stony Brook University", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 49.5, "institution_score": 25, "track_score": 65, "milestone_score": 70, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "Gem-miR-15a为吉西他滨化学修饰的miR-15a，保留miR-15a靶向WEE1/CHK1/BMI1等多靶点抑癌机制，同时整合吉西他滨化疗作用。大学机构+非主流modality但显示强体外/体内疗效及克服耐药潜力，得分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/2335", "id": "mlXM_5wBX1NQZOEH-LS6", "source_drug_name": "Gem-miR-15a", "title": "Overcoming drug resistance by novel gemcitabine-modified miR-15a in colorectal cancer", "abstract_text": "Colorectal cancer (CRC) is the third most prevalent cancer globally. Despite therapeutic advances, chemoresistance remains a major challenge, with ~20-30% of advanced-stage CRC patients experiencing recurrence within the first five years of treatment. Growing evidence suggests that targeting DNA damage response proteins, such as ATR/ATM, WEE1, and CHK1, is critical for overcoming resistance. In this regard, microRNAs (miRNAs) offer great therapeutic potential, as they can simultaneously target multiple signaling pathways and their dysregulation is widely implicated in cancer. Notably, tumor-suppressor miRNA-15a (miR-15a) is frequently downregulated in CRC and has been associated with poor patient prognosis. While miR-15a restoration has shown great promise, effective miRNA delivery remains a significant challenge due to its instability. Various chemical modifications have been shown to greatly enhance the stability of miRNAs. One such modification, 5-FU modified miR-15a (5-FU-miR-15a) was demonstrated as a promising therapeutic in CRC by our lab. Building on this, we engineered a new gemcitabine-modified miR-15a (Gem-miR-15a), which integrates the tumor-suppressive properties of miR-15a with the chemotherapeutic ability of gemcitabine. Though not a standard therapy in CRC, gemcitabine is emerging as an alternative for advanced refractory and resistant cases. Thus, we hypothesized that Gem-miR-15a would have an enhanced therapeutic advantage in overcoming chemoresistance to standard drugs, such as 5-FU. In this study, we assessed the effects of Gem-miR-15a on cell viability, apoptosis, and cell cycle progression of various parental (HCT116, SW480, SW620, HT-29) and 5-FU resistant CRC cell lines. Gem-miR-15a drastically reduced cell viability in both parental (IC50=1-10nM) and resistant cells (IC50=4.08 nM) without any delivery vehicle, significantly induced apoptosis, and caused an S-phase cell cycle arrest. Gem-miR-15a demonstrated dramatically increased cytotoxicity, with an almost 1000-fold reduction in IC50 as compared to the standard drug, 5-FU. The effects were consistent in 3D spheroids (IC50=9.76 nM) and patient-derived organoids (IC50=6-14 nM), too. The modification retained the target specificity of the native miR-15a, and downregulated key oncogenes like WEE1, CHK1 and BMI1 which was confirmed by western blotting. Additionally, Gem-miR-15a demonstrated strong synergy with oxaliplatin (Synergy score: 11.03). Experiments were done in triplicate (n=3) and analyzed using Student’s t-test (p < 0.05). Gem-miR-15a (4mg/kg) was also significantly able to reduce the tumor growth in in vivo metastatic mouse models, as compared to the mice treated with vehicle alone, with no visible toxicities. Hence, our findings establish Gem-miR-15a as a potent and multi-targeted therapeutic candidate capable of overcoming chemoresistance in CRC.", "source_company": "Stony Brook University", "source_org_type": "大学", "row_number": 943, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "antibody-drug conjugate", "company": "UCSF - University of California San Francisco", "org_type": "大学", "target": "未披露", "modality": "ADC", "importance_level": "低", "total_score": 49.5, "institution_score": 30, "track_score": 85, "milestone_score": 40, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "药物为针对辐射诱导表面蛋白（具体靶点未披露）的ADC，旨在重编程肿瘤微环境并消除肿瘤及免疫抑制细胞；机构为大学学术型，得分较低，但ADC赛道及辐射诱导新靶点策略有一定热度和创新性，整体处于preclinical早期阶段。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4275", "id": "N57M_5wBZznHJdnt_W3O", "source_drug_name": "antibody-drug conjugate", "title": "Leveraging radiation inducible surface protein targets for tumor microenvironment reprogramming", "abstract_text": "Radiation Therapy (RT) is one of the most common treatments for patients with solid tumors, administered to over 50% of patients. Failure of tumor control following RT, however, is a significant clinical challenge. In the present study, we identify a suite of novel proteins as radiation-inducible surface proteins across a variety of cancers, including breast and non-small cell lung cancers. Specific proteins characterized act as enzymes which deplete metabolic substrates, thus altering both the tumor microenvironment (TME) as well as cell intrinsic function. Using cell-surface capture mass spectrometry, bulk-RNA sequencing, fluorescence spectrometry, and cytometry by time of flight (CyTOF), we comprehensively characterize our target upregulation following RT, both as a surface protein and the enzymatic consequence of perturbation. To increase induction of surface expression, we evaluated combinatorial strategies of RT with small molecules and other soluble factors. These combinations significantly increased expression in vitro in both mouse and human non-small cell lung cancer cell lines. Additionally, in vivo, tumor-targeted RT/combination treatment significantly upregulated our protein of interest on tumor cells, as well as on a subset of macrophages and fibroblasts. Functional investigation suggests these macrophages and fibroblasts may have an immunosuppressive role within the TME. Leveraging these findings, we developed directed therapies, including antibody-drug conjugates (ADCs) and antigen-specific chimeric antigen receptor (CAR) T cells, to ablate both tumor and immunosuppressive cells with increased levels of the target, providing a more conducive combinatorial therapy to control tumors. In conclusion, we have identified and characterized a radiation-inducible therapeutic target, providing framework for reprogramming the TME and improving treatment efficacy.", "source_company": "UCSF - University of California San Francisco", "source_org_type": "大学", "row_number": 985, "target_meta": "not available", "MOA_meta": "抗体偶联药物"}, {"drug_name": "PLK1-PROTAC", "company": "Soonchunhyang University Cheonan Hospital", "org_type": "医院", "target": "PLK1", "modality": "PROTAC", "importance_level": "低", "total_score": 49.5, "institution_score": 25, "track_score": 85, "milestone_score": 45, "field_heat_score": 60, "bonus_score": 2, "brief_reason": "靶向PLK1的PROTAC在结直肠癌模型中联合奥沙利铂显示增强抑瘤和逆转化疗耐药作用。机构为医院学术型，preclinical阶段体外+体内数据初步积极但非突破性，PROTAC+PLK1赛道有热度但整体开发早期且无产业化机构支持导致总分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8730", "id": "Yp7M_5wBZznHJdnt_W3O", "source_drug_name": "PLK1-PROTAC", "title": "Functional role of PLK1 in colorectal cancer progression and its potential to chemoresistance", "abstract_text": "OBJECTIVE\nColorectal cancer is a cancer with high prevalence and mortality rates worldwide, treated with surgery, chemotherapy, and radiation therapy depending on the stage. Advanced colorectal cancer is mostly curable by surgical excision combined with chemotherapy remains the primary treatment for most patients with advanced colorectal cancer. Drug resistance is one of the major obstacles in colorectal cancer treatment, highlighting the need for new therapeutic targets. Polo-like kinase 1(PLK1), a key regulator of the cell cycle, is frequently overexpressed in colorectal cancer as well as various malignancies and associated with poor prognosis. To explore the mechanisms of chemoresistance in colorectal cancer and identify potential strategies to overcome it, we investigated the functional role of PLK1 and its impact on drug sensitivity.\nMETHODS\nPLK1 was silenced using siRNA, and functional studies assessing proliferation, migration, invasion, and wound healing were conducted to investigate its role in colorectal cancer. To evaluate chemoresistance, colorectal cancer cells were treated with oxaliplatin. Additionally, we assessed the drug sensitivity of the oxaliplatin versus PLK1-PROTAC+oxaliplatin to evaluate its impact on cell survival. Subcutaneous implantation of CRC cell line-derived tumors was performed in BALB/c nude mice to assess tumor growth after drug treatment.\nRESULTS\nSuppression of PLK1 expression significantly impaired function of colorectal cancer. Colorectal cancer cells with low PLK1 expression exhibited significantly increased sensitivity to oxaliplatin. Compared to oxaliplatin alone, treatment with a PLK1-targeting PROTAC in combination with oxaliplatin significantly reduced colorectal cancer cell viability. In the in vivo study, PLK1-PROTAC exerted significantly enhanced suppression of tumor growth compared with Oxaliplatin.\nCONCLUSION\nSuppression of PLK1 expression led to a significant decrease in colorectal cancer cell function highlighting its essential role in sustaining tumor growth and metastatic functions. These findings suggest that PLK1 may serve as a potential therapeutic target for inhibiting colorectal cancer progression and overcoming chemoresistance.", "source_company": "Soonchunhyang University Cheonan Hospital", "source_org_type": "医院", "row_number": 1016, "target_meta": "PLK1", "MOA_meta": "PROTAC"}, {"drug_name": "NPP-2-21", "company": "University of Michigan", "org_type": "大学", "target": "UBA1", "modality": "prodrug", "importance_level": "低", "total_score": 49.5, "institution_score": 35, "track_score": 75, "milestone_score": 40, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "NPP-2-21为UBA1抑制剂的理性设计前药，可改善药理特性并提升抗肿瘤活性；大学机构早期preclinical研究，靶点UBA1在癌症中有潜力但非热门，整体开发阶段初步导致总分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11460", "id": "Y57M_5wBZznHJdnt_W3O", "source_drug_name": "NPP-2-21", "title": "NPP-2-21: A rationally designed prodrug of a UBA1 inhibitor with improved pharmacologic properties and antitumor activity", "abstract_text": "Abstract is embargoed at this time.", "source_company": "University of Michigan", "source_org_type": "大学", "row_number": 1017, "target_meta": "UBA1", "MOA_meta": "其他"}, {"drug_name": "PI3Ka activator", "company": "University College London Cancer Institute", "org_type": "大学", "target": "PI3Kα", "modality": "other", "importance_level": "低", "total_score": 49.5, "institution_score": 35, "track_score": 65, "milestone_score": 55, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "使用PI3Kα激活剂在体外PDO模型中富集proCSC状态以增加放化疗诱导凋亡，属于工具化合物而非开发药物；大学机构基础研究，preclinical阶段机制探索，无明确临床推进，综合热度有限。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9326", "id": "oZ3ECZ0B4z9FlvORyiZD", "source_drug_name": "PI3Ka activator", "title": "Stem cell transdetermination is a targetable driver of therapeutic response to neoadjuvant chemoradiotherapy in rectal cancer", "abstract_text": "Neoadjuvant chemoradiotherapy (nCRT) is used in about one third of rectal cancer cases in the UK, but treatment response is heterogeneous, leading to difficulties in response prediction and sensitization. Phenotypic plasticity, driven by both cell-intrinsic mutations and cell-extrinsic signals from the tumour microenvironment (TME) has been shown to influence therapy resistance in colorectal cancer. This study explores the role of proliferative cancer stem cells (proCSCs) and revival cancer stem cells (revCSCs) in CRT response, and how phenotypic plasticity can be targeted to improve CRT sensitivity.\nPatient-derived organoids (PDOs) from a cohort of 10 patients with microsatellite-stable rectal cancer were subject to combinatorial perturbations of radiation, chemotherapy, exploratory radiosensitizers, and co-culture with cancer associated fibroblasts (CAFs). PDOs were analysed 3 hours and 48 hours after radiation in triplicate, totalling 2,400 experimental conditions. PDOs were analysed using single-cell thiol-organoid barcoding in situ mass cytometry (TOBis MC), enabling high-dimensional characterisation of CSC states, DNA damage responses, canonical signalling pathways, cell cycle, and apoptosis.\nPDOs displayed heterogeneous, patient-specific responses to CRT, and could be classified in the following manner: 1) high signalling response, high apoptosis; 2) high signalling response, low apoptosis; and 3) low signalling response, low apoptosis. Therapy-induced apoptosis did not correlate with on-target DNA damage, but instead strongly aligned with baseline stem cell index (SCI), a metric that describes the relative proCSC-revCSC ratio of each PDO. Higher rates of apoptosis were seen in PDOs that were proCSC-dominant at baseline (high-SCI), whereas revCSC-dominant PDOs (low-SCI) were more resistant apoptosis after treatment. In certain low-SCI PDOs, the proCSC population could be enriched using a PI3Ka activator before radiation, resulting in increased apoptosis after radiation with little toxicity. After CRT, a significant reduction in SCI was seen across the cohort. Blockade of revCSC transdetermination with a YAP/TEAD1 inhibitor also resulted in increased radiation-induced apoptosis. Highly plastic PDOs exhibiting large differences SCI following CRT were identified by high DACH1 expression.\nThis study suggests that the initial level of on-target DNA-damage following CRT does not dictate cell death, rather, it is due to what state the cancer cell is in when the damage occurs. We find that rectal cancer cells in a proCSC state typically enter apoptosis in response to DNA damage, whereas cancer cells in the revCSC state survive therapy. We also find that pharmacologically enriching proCSCs and blocking access to the revCSC state can sensitize PDOs to CRT, and may have therapeutic importance in treating rectal cancer.", "source_company": "University College London Cancer Institute\nUniversity College London (UCL) Cancer Institute", "source_org_type": "大学", "row_number": 1036, "target_meta": "PI3Kα", "MOA_meta": "其他"}, {"drug_name": "CAR-T cell therapy", "company": "Peking University Cancer Hospital", "org_type": "医院", "target": "CLDNs", "modality": "CAR", "importance_level": "低", "total_score": 49.5, "institution_score": 35, "track_score": 85, "milestone_score": 30, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "该报告聚焦CLDNs家族的细胞治疗，包括CAR-T开发经验及下一代策略，但摘要未提供具体内容或数据，仅为教训总结。北京大学肿瘤医院作为国内知名机构，但非头部药企，缺乏具体里程碑进展，赛道虽热门(CLDN相关CAR-T在实体瘤有高热度)但本条信息无实质创新披露。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/424", "id": "tp7M_5wBZznHJdnt_W3O", "source_drug_name": "CAR-T cell therapy", "title": "Cellular therapies targeting CLDNs: Lessons from CAR-T development and next-generation strategies", "abstract_text": "There is no abstract associated with this presentation.", "source_company": "Peking University Cancer Hospital", "source_org_type": "医院", "row_number": 1080, "target_meta": "CLDN", "MOA_meta": "其他"}, {"drug_name": "versikine", "company": "Rush University Medical Center", "org_type": "医院", "target": "未披露", "modality": "LNP-mRNA or recombinant protein", "importance_level": "低", "total_score": 49.5, "institution_score": 25, "track_score": 75, "milestone_score": 70, "field_heat_score": 65, "bonus_score": 3, "brief_reason": "versikine为versican蛋白酶解产生的matrikine片段，具有免疫调节作用，可恢复肿瘤基质免疫信号网络逆转检查点抑制剂耐药。机构为医院学术型，得分较低；赛道涉及免疫调节新机制及mRNA递送有一定热度，但preclinical阶段且无公司推进导致总分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10451", "id": "657M_5wBZznHJdnt_W3O", "source_drug_name": "versikine", "title": "Biomarker-driven restoration of tumor provisional matrix signaling network reverses resistance to checkpoint inhibition immunotherapy", "abstract_text": "Specialized immune niches located in the stroma-tumor junction promote interactions between tumor-resident antigen-presenting cells and effector lymphocytes that are required for immunotherapy efficacy. We have hypothesized that this stromal-based immune crosstalk may be regulated by provisional extracellular matrix signals, analogous to the early-stages of wound healing where provisional matrix hosts robust immune activity. A cardinal provisional matrix remodeling event, the regulated proteolysis of the large proteoglycan versican (VCAN) generates an immunomodulatory fragment (matrikine), versikine, that engages adaptive immunity. We have previously shown that VCAN proteolysis correlates with T-cell infiltration across multiple solid and liquid cancers with the most immune-evasive cancers showing low to negligible rates of VCAN proteolysis (e.g., 0% in pancreatic adenocarcinoma). A recent clinical trial generated informative prospective data linking VCAN proteolysis with immunotherapy outcomes: patients whose metastatic colorectal tumors categorized as VCAN proteolysis-weak (VPW, 60% of cases) demonstrated inferior responses to checkpoint inhibition (CPI, pembrolizumab) and worse outcomes compared to VCAN proteolysis-predominant (VPP, 40%) cases. Leveraging these prospective trial data, we hypothesized that versikine therapy may rationally reverse the immunosuppression associated with the prevalent VPW phenotype. To tailor versikine therapy to specific human biomarker-stratified tumor phenotypes, we studied experimental models replicating partially T-permissive VPW-VCANlo human cancers and poor-prognosis, immune-exclusionary VPW-VCANhi cancers. Across VPW-like tumors, versikine promoted the stromal accumulation of CD40lghiIcoshiFoxp3neg Tfh-like CD4+ T cells that engaged dendritic cells (DC) and CD8+ T cells in “immune triads” even at baseline (prior to CPI), concurrently with the intratumoral expansion of activated CD8+ T cells expressing cytolytic molecules (granzymes, perforin). In VPW-VCANlo tumors, versikine delivered as LNP-mRNA or recombinant protein demonstrated monotherapy activity, dependent on Batf3-lineage DC and CD8+ T cells. When combined with single-agent CPI, versikine cured most VPW-VCANlo tumors with memory to tumor re-challenge. In VPW-VCANhi tumors, versikine synergized with combination immunotherapy modulating “mature DCs enriched in immunoregulatory molecules” (mregDC). Our data provide mechanistic rationale for the biomarker-stratified, therapeutic restoration of a provisional matrix-regulated immune signaling network to reverse resistance to CPI. Moreover, the data highlight the need to reevaluate prior approaches to globally disrupt tumor stroma in favor of biomarker-driven, pathway-focused harnessing of stromal signals that modulate anti-tumor immunity.", "source_company": "Rush University Medical Center", "source_org_type": "医院", "row_number": 1116, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "CAR T cell therapy", "company": "Standard BioTools", "org_type": "公司", "target": "未披露", "modality": "CAR", "importance_level": "低", "total_score": 49.5, "institution_score": 45, "track_score": 85, "milestone_score": 30, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "该记录为Standard BioTools公司推广其CyTOF质谱流式技术，用于分析CAR-T细胞疗法产品中功能异质性和潜在抑制性细胞，无具体药物靶点或候选药物披露。机构为工具/仪器公司而非药物研发主体，得分较低；虽细胞治疗赛道热门，但仅为分析工具而非药物开发里程碑，整体重要性有限。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5318", "id": "sJ3ECZ0B4z9FlvORyiZD", "source_drug_name": "CAR T cell therapy", "title": "Use of a 50-marker mass cytometry intracellular cytokine staining panel reveals unforeseen functional diversity within cell therapy products and unmasks potential efficacy 'saboteurs'", "abstract_text": "Cell-based therapies have proven to be highly effective against certain cancers, yet improvements are needed to extend these successes to a wider variety of malignancies. Single-cell functional assessment of cell therapy products is customarily limited to Th1 cytokines (such as IFN-γ) and the cell survival/proliferative mediator IL-2, overlooking the cellular heterogeneity of CAR T products. This heterogeneity includes diverse antigen-experienced αβ T cells previously differentiated into distinct lineages (for example, Type 1, 2, 17, Treg) and innate T cell populations (iNKT, MAIT, γδ T), with many of the latter pre-programmed to exert immunosuppressive and/or cell repair effector functions. This diversity introduces potential “saboteur” cells with off-target effects that may undermine therapeutic efficacy. Surface marker profiling is insufficient for functional characterization, yet traditional flow cytometry lacks resolution for certain intracellular targets, particularly immunosuppressive cytokines. Mass cytometry (CyTOF™ technology) overcomes this technical limitation, providing superior intracellular signal resolution in the context of large panel analyses, a prerequisite of deep functional assessment of single cells. We hypothesized that there are sizeable proportions of saboteur T cells in cell therapy products that exert functions after stimulation that act in direct opposition to the therapeutic intention of the drug. To assess this, we developed a 50-marker CyTOF intracellular cytokine staining (ICS) panel with 24 functional readouts. This enabled clear detection of individual human T cells producing immunosuppressive cytokines such as IL-10, IL-13 and TGF-β, and measured the composite cytokine responses of both T cells in peripheral blood mononuclear cells (PBMC) and cell therapy products. Our data revealed an unforeseen prevalence of T cells that cross dogmatic lineage paradigms when stimulated. For example, after mitogen stimulation, approximately 30% of T cells from both peripheral blood and a cell therapy product produced the TGF-β-inducing cytokine amphiregulin (AREG), often concurrently with IFN-γ within the same cells. In addition, using the CyTOF ICS panel on TCR-stimulated T cell populations revealed peptide-specific production of AREG, IL-13, IL-4 and MIP-1β by CD8 T cells in PBMC, suggesting CAR T products may release unmeasured cytokines in response to specific CAR antigen binding. From these results, we anticipate application of CyTOF ICS technology to cell therapy testing and modification will transform our understanding of these therapies and ultimately enhance their efficacy.", "source_company": "Standard BioTools", "source_org_type": "公司", "row_number": 1128, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "programmable nucleic acid sensing system", "company": "Dana-Farber Cancer Institute", "org_type": "医院", "target": "driver and truncal fusion RNAs", "modality": "other", "importance_level": "低", "total_score": 49.5, "institution_score": 40, "track_score": 75, "milestone_score": 30, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "该系统针对driver and truncal fusion RNAs作为治疗触发器，属于核酸传感平台，可实现精准肿瘤特异性触发；机构为知名癌症医院但非头部药企，处于preclinical概念阶段无具体数据披露，赛道新兴但热度中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/2686", "id": "M57M_5wBZznHJdnt_W7O", "source_drug_name": "programmable nucleic acid sensing system", "title": "Leveraging driver and truncal fusion RNAs as therapeutic triggers with a programmable nucleic acid sensing system", "abstract_text": "There is no abstract associated with this presentation.", "source_company": "Dana-Farber Cancer Institute", "source_org_type": "医院", "row_number": 1160, "target_meta": "RNA", "MOA_meta": "其他"}, {"drug_name": "ELX19", "company": "University Hospital of Cologne", "org_type": "医院", "target": "SIX1", "modality": "PROTAC", "importance_level": "低", "total_score": 49.5, "institution_score": 25, "track_score": 85, "milestone_score": 45, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "ELX19为SIX1特异性PROTAC，在食管腺癌细胞系中显示特异性降解SIX1并抑制增殖/诱导凋亡，但仅为医院学术机构的早期体外研究。PROTAC赛道热度较高，但机构非商业化主体且无体内/临床数据导致整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5678", "id": "Sp7M_5wBZznHJdnt_W7P", "source_drug_name": "ELX19", "title": "Development of a SIX1-specific PROTAC for the treatment of esophageal adenocarcinoma", "abstract_text": "Esophageal adenocarcinoma belong to the cancer entities with a sharply increasing incidence. Though multimodal therapies have improved outcomes, prognoses remain poor in advanced stages and the 5-year survival rate is only between 20 to 25%. For this purpose, new therapeutic options are urgently necessary. In this context, this project investigated a SIX1-specific PROTAC (ELX19) in EAC - including potential adverse effects on the immune system. SIX1 is an embryonic transcription factor, which is required during embryogenesis for the development of various organs and tissues. In contrast, it is no longer or only weakly expressed in adult tissue. However, many cancers show a reactivation of cancer, which leads to different pro-tumorigenic features, making SIX1 a potentially therapeutic target. We first tested the efficiency of ELX19 in degrading SIX1 via WB and ELISA. Thereby, a higher SIX1 expression correlated with a better degradation efficiency, leading to a DC50 of below 1 µM in FLO-1 cells. ELX19 also reduced proliferation and increased apoptosis in FLO-1 cells. Importantly, ELX19 did not affect proliferation and apoptosis in a cell line with low SIX1 expression (OE19) suggesting that the effects caused by ELX19 are SIX1-specific. As adverse effects on the immune system can be a major impediment for further clinical development, we tested the effect of ELX19 on primary T helper and cytotoxic T cells. Thereby, unspecific effects only started 3 µM which is common for VHL-based PROTACs. In conclusion, these preliminary results show the potential of a SIX1-targeting PROTAC for the treatment of esophageal adenocarcinoma.", "source_company": "University Hospital of Cologne", "source_org_type": "医院", "row_number": 1178, "target_meta": "SIX1", "MOA_meta": "PROTAC"}, {"drug_name": "PLK1-targeting PROTAC", "company": "Soonchunhyang University Cheonan Hospital", "org_type": "医院", "target": "PLK1", "modality": "PROTAC", "importance_level": "低", "total_score": 49.5, "institution_score": 25, "track_score": 85, "milestone_score": 45, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "靶向PLK1的PROTAC在卵巢癌细胞中显示蛋白降解优于紫杉醇、克服化疗耐药并抑制转移特性，但仅为医院学术机构的体外细胞水平初步研究。机构非药企导致基础分低，PROTAC赛道+PLK1靶点热度较高但整体开发阶段早、无明确临床推进。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6468", "id": "WJ7M_5wBZznHJdnt_W7P", "source_drug_name": "PLK1-targeting PROTAC", "title": "Mechanistic insights into PLK1 target inhibition in ovarian cancer: Functional suppression and PROTAC-based therapeutic agents", "abstract_text": "OBJECTIVE\nThis study aimed to identify the oncogenic role of PLK1(Polo-like kinase 1) in ovarian cancer and evaluate its potential as a PROTAC therapeutic target candidate. We also investigated the change in the functional properties of cancer by PLK1 inhibition and whether it is possible to improve cell viability rate through PROTAC-based PLK1 protein degradation.\nMETHODS\nFunctional studies were conducted using PLK1 siRNA in SKOV3 cell lines. Changes in cell proliferation, migration, invasion, and wound-healing ability were evaluated following PLK1 silencing. Quantitative RT-PCR was used to measure PLK1 expression in cell lines and in benign, malignant ovarian tumor tissue samples.In addition, we evaluated the effect on sensitivity in ovarian cancer cell lines and paclitaxel-resistant ovarian cancer cell lines using PLK1 target PROTAC.\nRESULTS\nExpression of PLK1 at the RNA level is significantly overexpressed in ovarian cancer cells compared to normal cells. Also, PLK1 expression was significantly overexpressed in malignant ovarian tumor compared to benign ovarian neoplasm. PLK1 silencing significantly reduced cell proliferation and decreased migration and invasion by 50-60%. Cell viability assays performed in both parental and paclitaxel-resistant ovarian cancer cell lines demonstrated that treatment with the PLK1-targeting PROTAC resulted in a significantly higher level of cell death compared to paclitaxel.\nCONCLUSION\nOur results demonstrate that PLK1 inhibition at both the RNA and protein levels suppresses the metastatic characteristics of ovarian cancer and highlights its potential as a therapeutic target. Targeting PLK1 in ovarian cancer may contribute to the inhibition of metastatic aibilty and the overcoming of chemoresistance.", "source_company": "Soonchunhyang University Cheonan Hospital", "source_org_type": "医院", "row_number": 1185, "target_meta": "PLK1", "MOA_meta": "PROTAC"}, {"drug_name": "cell-permeable peptides that block the VPS72-H2A.Z interaction", "company": "Henry Ford Health System", "org_type": "医院", "target": "VPS72-H2A.Z interaction", "modality": "other", "importance_level": "低", "total_score": 49.5, "institution_score": 35, "track_score": 65, "milestone_score": 45, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "药物为阻断VPS72-H2A.Z相互作用的细胞穿透肽，靶向表观遗传调控以抑制肺腺癌恶性表型。由医院机构开发，处于早期研究阶段，仅体外验证，赛道新颖但非热门modality且无临床进展，导致整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/2096", "id": "gZ7M_5wBZznHJdnt_W7P", "source_drug_name": "cell-permeable peptides that block the VPS72-H2A.Z interaction", "title": "The VPS72-H2A.Z-axis is an underappreciated oncogenic vulnerability in lung adenocarcinoma", "abstract_text": "Lung adenocarcinoma (LUAD), the most common subtype of non-small cell lung cancer (NSCLC), frequently relies on epigenetic plasticity to support growth, stress adaptation, and therapeutic escape. Among the chromatin mechanisms enabling this plasticity, histone variant exchange is central. Incorporation of specific variants reshapes DNA accessibility and transcriptional programs, underpinning cancer cell adaptability. VPS72, a histone chaperone shared by the SRCAP and TIP60 complexes, mediates ATP-dependent deposition of the H2A.Z-H2B dimer into regulatory chromatin, thereby promoting proliferation, lineage state, immune evasion, and treatment tolerance transcriptional programs. H2A.Z deposition is linked to aggressive malignancy; however, the contribution of VPS72 itself to LUAD progression remains undefined. Given its central role in H2A.Z loading, the VPS72-H2A.Z axis may represent a key epigenetic driver and potentially targetable vulnerability. TCGA LUAD datasets were analyzed to profile VPS72 expression, genomic correlates, and functional relevance. VPS72 was significantly upregulated relative to normal tissue and associated with greater genomic instability, higher tumor mutational burden, stronger hypoxia signatures, earlier clinical detectability, and reduced overall survival. High VPS72 expression was also observed in female patients and ever-smokers, indicating exposure-linked modulation. Functional evaluation in LUAD models showed that genome-wide CRISPR and RNAi screens identified VPS72 as a major fitness gene. shRNA-mediated VPS72 depletion reduced proliferation and Ki-67 expression, reduced colony formation, impaired migration and invasion, and abrogated anchorage-independent growth. Transcriptional profiling revealed that VPS72 loss strongly repressed MYC- and E2F-driven cell-cycle programs and disrupted metabolic pathways, including heme biosynthesis, mitochondrial respiration, calcium signaling, and hypoxia adaptation. Although H2A.Z itself is not directly targetable, VPS72 role in its deposition creates a druggable interface. To exploit this, we developed cell-permeable peptides that block the VPS72-H2A.Z interaction, which phenocopied VPS72 knockdown by inducing apoptosis and suppressing LUAD cell growth in a dose-dependent manner. Collectively, these findings identify VPS72 as a central epigenetic regulator and therapeutically actionable vulnerability in LUAD. Disrupting the VPS72-H2A.Z axis attenuates oncogenic transcriptional programs and malignant behaviors, offering a promising strategy to overcome epigenetic plasticity and treatment resistance in aggressive NSCLC.", "source_company": "Henry Ford Health System", "source_org_type": "医院", "row_number": 1212, "target_meta": "VPS72,H2AZ2", "MOA_meta": "其他"}, {"drug_name": "compounds", "company": "Sanford Burnham Prebys Medical Discovery Institute", "org_type": "研究机构", "target": "未披露", "modality": "inhibitor", "importance_level": "低", "total_score": 49, "institution_score": 35, "track_score": 75, "milestone_score": 40, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "摘要仅描述通过筛选发现针对BRD8缺失后脆弱性的小分子化合物，未明确药物靶点和具体机制，仅处于早期筛选阶段。研究机构非商业化主体、开发阶段初步且无明确里程碑导致总体重要性较低，但表观遗传调控TP53WT胶质母细胞瘤的机制有一定新颖性和领域潜力。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/2217", "id": "PFXM_5wBX1NQZOEH-LG5", "source_drug_name": "compounds", "title": "Unraveling novel epigenetic therapies for the treatment of TP53WTglioblastoma", "abstract_text": "Glioblastoma (GBM) remains the most aggressive and treatment-resistant primary brain tumor in adults, with median patient survival of only 12-15 months despite current standard-of-care therapies. To identify new therapeutic strategies, we investigated how chromatin remodeling regulates cell-state transitions in TP53 wild-type (TP53WT) GBM, which represents the majority of cases. We found that the chromatin regulator BRD8, a component of the EP400 complex, acts as a key suppressor of p53 activity. BRD8 maintains H2A.Z occupancy at p53 target loci to repress its tumor-suppressive paradigm. Depletion of BRD8 disrupts this interaction, increases chromatin accessibility, and reactivates p53-dependent transcriptional programs, resulting in a stable cell cycle arrest and a senescent phenotype accompanied by widespread transcriptomic reprogramming. Through small-molecule screening, we identified compounds that selectively impair the survival of BRD8-deficient cells, revealing specific vulnerabilities associated with this arrested state. We further discovered that the histone variant, macroH2A (mH2A), enforces the changes in chromatin accessibility and transcriptional output following BRD8 perturbation, functioning as epigenetic switches that stabilize this altered cell state. Together, these findings reveal a chromatin-based mechanism governing proliferative control in GBM and highlight actionable vulnerabilities that could be exploited through targeted pharmacologic intervention.", "source_company": "Sanford Burnham Prebys Medical Discovery Institute", "source_org_type": "研究机构", "row_number": 11, "target_meta": "not available", "MOA_meta": "抑制剂"}, {"drug_name": "xxx", "company": "West China Hospital of Sichuan University", "org_type": "医院", "target": "未披露", "modality": "inhibitor", "importance_level": "低", "total_score": 49, "institution_score": 30, "track_score": 70, "milestone_score": 65, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "药物xxx为ELAVL3抑制剂，通过抑制ELAVL3破坏NOTCH2信号通路稳定性，维持SCLC神经内分泌表型并逆转耐药相关非NE转化；机构为医院学术型，preclinical阶段有PDX和器官芯片模型支持但无明确临床里程碑，赛道为SCLC新型靶点调控但非热门modality或靶点。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1921", "id": "4lXM_5wBX1NQZOEH-LO6", "source_drug_name": "xxx", "title": "ELAVL3 post-transcriptionally regulation of the NOTCH2 signaling pathway shapes the plasticity of small cell lung cancer", "abstract_text": "Background: Small cell lung cancer (SCLC) is a highly aggressive and heterogeneous malignancy, typically classified into four phenotypic subtypes by different transcription factors, referred to as ANYP. Recent studies have highlighted the plasticity between these subtypes, especially neuroendocrine (NE)/ non-NE states, which closely linked to treatment resistance. Emerging evidence suggests that stabilizing the SCLC phenotype could be advantageous for improving clinical outcomes. In this study, we identified a novel RNA-binding protein, ELAVL3, as a key player in the plasticity of SCLC. We discovered that ELAVL3 promotes a more NE-like progression of SCLC by post-transcriptionally disrupting the NOTCH2 signaling pathway. This finding offers new insights into the molecular mechanisms driving SCLC plasticity and proposes potential targets for therapeutic intervention.\nMethods and Result: Through analysis of single-cell RNA sequencing data from 20 of our SCLC patients and some public databases, ELAVL3 expression is found to be positively correlated with NE signatures in both SCLC cell lines and patient tumors. Transcriptomic analysis and Western blotting results in SCLC cell lines showed that pharmacological inhibition of ELAVL3 with xxx activates NOTCH signaling pathways and induces the loss of NE features, while ELAVL3 overexpression reduces NOTCH2 mRNA levels and helps to maintain the NE characteristics. Some molecular experiments, including RNA immunoprecipitation (RIP)-qPCR, RIP-sequencing and RNA pulldown, further discovered that ELAVL3 extensively binds to and interferes with the RNA stability of NOTCH2 signaling pathway members, thereby enhancing the NE program.Our previous studies have found that immunotherapy (IO) combined with radiotherapy (RT) can be effective for chemotherapy resistant subcutaneous SCLC, which is non-NE type, for a certain period of time. By single-cell RNA sequencing of tumor at multiple time points after IO+RT, we identified a close association among highly expressed ELAVL3, inactivated NOTCH signaling, restored NE characteristics and acquired therapy resistance. After testing various combination therapies in SCLC cell lines, patient-derived organoids, patient-derived tumor xenograft model, and murine SCLC model, we revealed that the inhibition of ELAVL3 hold their differentiation into non-NE types, which better corresponded to the immuno-combination therapies for SCLC after chemotherapy resistance.\nConclusions: This study nominates ELAVL3 as a key regulator of the NE state plasticity and defines a novel therapeutic strategy for SCLC.", "source_company": "West China Hospital of Sichuan University", "source_org_type": "医院", "row_number": 61, "target_meta": "not available", "MOA_meta": "抑制剂"}, {"drug_name": "AAP", "company": "China Medical University", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 49, "institution_score": 25, "track_score": 70, "milestone_score": 60, "field_heat_score": 65, "bonus_score": 3, "brief_reason": "AAP为苯硼酸功能化的青蒿琥酯氨基酸修饰前药纳米粒，通过PBA介导主动靶向和EPR效应递送青蒿琥酯诱导铁死亡治疗结直肠癌，机制为铁死亡放大但靶点未明确披露。大学机构研发处于preclinical阶段，铁死亡+纳米递送赛道有一定热度但非头部公司推动，整体开发价值有限。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6403", "id": "klXM_5wBX1NQZOEH-LS6", "source_drug_name": "AAP", "title": "Ferroptosis amplified by a tumor-targeted artesunate nano-derivative for effective colon cancer treatment", "abstract_text": "Background: Artesunate (ART), a proven antimalarial drug, is promising but has limited antitumor activity because of its poor stability, low potency, and lack of tumor selectivity. While its effect is linked to ferroptosis, an iron-dependent form of cell death driven by lipid peroxidation, clinical translation in oncology requires enhanced drug delivery and targeting. We hypothesized that engineering a tumor-targeted nanoparticle of an ART prodrug could amplify ferroptosis induction and therapeutic efficacy against colorectal cancer (CRC).\nMethods: We systematically designed and synthesized six amino acid-modified ART derivatives. The most potent conjugate was further functionalized with 3-aminophenylboronic acid (PBA) to create the final prodrug, AAP. AAP self-assembled into nanoparticles (AAP NPs) via a one-step precipitation method. The size, PDI, and morphology of the NPs were characterized. Efficacy was evaluated in multiple CRC cell lines (CT26, HCT116, SW480, SW620) and a hepatoma cell line (Huh7) via CCK-8 assays. Cellular uptake was visualized via coumarin-6-loaded NPs. The antitumor effect, systemic safety, survival benefit, and mechanism of AAP NPs were comprehensively investigated in a BALB/c mouse model bearing CT26 tumors.\nResults: AAP demonstrated superior in vitro cytotoxicity compared with native ART, with IC50 values 1.77- to 2.09-fold lower across CRC and hepatoma cells. The resulting AAP NPs were monodisperse spheres with a uniform size of 174.44 ± 9.97 nm and a low PDI of 0.046. Compared with ART or ART-AA (no PBA), the completed AAP NPs exhibited significantly stronger, dose- and time-dependent cytotoxicity against all cancer cells tested (P < 0.05) and were effectively internalized by CT26 cells. In vivo, AAP NPs achieved the most potent tumor growth inhibition, reducing the tumor volume and weight to 531.29 ± 132.20 mm³ and 483.14 ± 118.91 mg, respectively, significantly outperforming the control, ART, and ART-AA NP groups (P < 0.05). Critically, AAP NPs significantly prolonged mouse survival (P < 0.05) . Mechanistically, AAP NP treatment led to significant accumulation of ROS in tumor tissues, confirming the induction of ferroptosis.\nConclusion: We developed a dual-targeted ART nanoprodrug that leverages PBA-mediated active targeting and the EPR effect. This strategy potently inhibits CRC growth by triggering ferroptosis and exhibits an excellent safety profile, offering a compelling approach to repurpose ART for targeted cancer therapy.", "source_company": "China Medical University", "source_org_type": "大学", "row_number": 78, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "intratumoral CD40 antibody", "company": "La Jolla Institute of Immunology", "org_type": "研究机构", "target": "CD40", "modality": "antibody", "importance_level": "低", "total_score": 49, "institution_score": 35, "track_score": 75, "milestone_score": 45, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "该药为靶向CD40的激动型抗体，通过瘤内给药结合IRE增强胰腺癌新抗原特异性T细胞反应，具有免疫激活机制，但摘要被embargo未披露具体数据。机构为非商业研究机构得分较低，临床前到早期临床转化潜力一般导致总分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/12186", "id": "Kp7ECZ0BZznHJdntvNYd", "source_drug_name": "intratumoral CD40 antibody", "title": "Irreversible electroporation (IRE) with intratumoral CD40 antibody increases T-cell reactivity to personalized neoantigens in locally advanced pancreatic cancer", "abstract_text": "Abstract is embargoed at this time.", "source_company": "La Jolla Institute of Immunology", "source_org_type": "研究机构", "row_number": 311, "target_meta": "CD40", "MOA_meta": "抗体"}, {"drug_name": "STING agonist", "company": "Johns Hopkins All Children's Hospital", "org_type": "医院", "target": "STING", "modality": "agonist", "importance_level": "低", "total_score": 49, "institution_score": 25, "track_score": 75, "milestone_score": 55, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "STING激动剂联合LTβR激活诱导成熟三级淋巴结构(TLS)，在多种肿瘤模型中显著抑制生长和转移，并增强抗PD-1疗效。机构为医院/学术型，处于preclinical阶段但机制新颖且临床转化潜力较高，故赛道热度较高但总分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6375", "id": "PVXM_5wBX1NQZOEH-LG5", "source_drug_name": "STING agonist", "title": "A little STING spices up tertiary lymphoid structures: Therapeutic induction of mature TLS by STING and lymphotoxin-β receptor activation confers immune protection against cancer metastasis", "abstract_text": "Significant clinical evidence demonstrates an association of tertiary lymphoid structure (TLS) formation with cancer survival. Clinically translatable pharmacologic/biologic agents that induce TLS-rich tumor immune environment could provide a breakthrough strategy to treat therapy-resistant cancers. Here, we show that simultaneous activation of innate immune effectors, STING and lymphotoxin-β receptor (LTβR), by their agonists induces the formation of multiple TLS in TLS-free tumors in a manner dependent on CD4+ and CD8+ T cells. Using this approach, functional TLS were induced in all treated mice, in different tumor types and anatomical sites—TLS developed in adenocarcinomas and sarcomas in the pancreas, mammary gland, skeletal muscle, and subcutaneous tissues. TLS also developed in the brain harboring gliomas. STING activation alone was insufficient for inducing B cell-containing TLS or eliciting long-term therapeutic effects. However, when combined with LTβR activation, it improved the fitness of TLS with B cell expansion and maturation to IgG-producing long-lived plasma cells and memory cells, exhibiting lymph node follicle-like germinal center responses within tumors. In addition, the treatment induced high endothelial venule formation, increased CD4+ T cell recruitment, memory CD8+ T cell expansion, and the accumulation of TCF1+ stem-like CD8+ T cells around TLS. These immune responses resulted in strong suppression of tumor growth and metastasis, with excellent survival benefit, demonstrating that the treatment successfully immunized mice against tumor cells. The STING/LTβR combination therapy also substantially improved the efficacy of anti-PD-1 immune checkpoint blockade in resistant tumors. The immediate early response to the combination therapy was mediated mainly by CD8+ T cells. The delayed but prolonged response was mediated by humoral immunity of B cells, which exerted a lasting anti-tumor effect together with the cellular immunity of CD8+ T cells and NK cells. Our finding establishes a foundation for the therapeutic induction of TLS in cancer. Unlike other reported strategies, TLS induction by this method does not require viral antigens or artificial genetic manipulations to boost immune response, making it feasible for clinical applications. The high-affinity tumor-specific IgG-producing long-lived plasma cells and memory B and T cells generated in these TLS could provide lifelong protection against tumor recurrence and metastases. Effective tumor immunization by this strategy is expected to improve other cancer immunotherapies and suggests broad therapeutic applications in cancer. Since STING agonists are clinically available and humanized agonistic antibodies to LTβR can be developed, this strategy is readily translatable to clinical use for cancer treatment.", "source_company": "Johns Hopkins All Children's Hospital", "source_org_type": "医院", "row_number": 349, "target_meta": "STING", "MOA_meta": "激动剂"}, {"drug_name": "CAR T cells", "company": "Cleveland Clinic Lerner Research Institute", "org_type": "研究机构", "target": "未披露", "modality": "CAR", "importance_level": "低", "total_score": 49, "institution_score": 40, "track_score": 85, "milestone_score": 30, "field_heat_score": 80, "bonus_score": 0, "brief_reason": "该研究聚焦VISTA-LRIG1轴对CAR T细胞持久性和功能的抑制机制，但药品本身为通用CAR T cells，未披露具体靶点或新型药物实体，仅为基础机制探讨。机构为知名研究机构但非头部药企，处于preclinical基础研究阶段，无明确开发里程碑。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11521", "id": "T1XM_5wBX1NQZOEH-LG5", "source_drug_name": "CAR T cells", "title": "The inhibitory VISTA LRIG1 axis impairs the persistence and function of CAR T cells", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Cleveland Clinic Lerner Research Institute", "source_org_type": "研究机构", "row_number": 364, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "HDAC inhibitors", "company": "National Cancer Institute", "org_type": "研究机构", "target": "HDAC", "modality": "inhibitor", "importance_level": "低", "total_score": 49, "institution_score": 45, "track_score": 65, "milestone_score": 35, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "HDAC抑制剂通过Brd4-Sp1/Sp3依赖方式转录上调NOX5表达并增加ROS产生，机制已在UM细胞系中阐明，但仅为preclinical机制研究，无临床开发进展。机构为政府研究机构而非药企、开发阶段早期且无明确药物候选、赛道非当前最热导致综合重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8657", "id": "YFXM_5wBX1NQZOEH-LG5", "source_drug_name": "HDAC inhibitors", "title": "HDAC inhibitors induce NOX5 expression in human uveal melanoma cells in a Brd4-Sp1/Sp3-dependent manner", "abstract_text": "Epigenetic reprogramming, particularly histone deacetylation (HDAC), and reactive oxygen species (ROS) play key roles in melanoma progression and the development of drug resistance. While various histone deacetylase inhibitors (HDACi) are already in clinical use for hematological cancers, recent studies indicate their potential effectiveness in melanoma models as well. Given the increasing interest in enhancing the therapeutic efficacy of HDACi, we investigated the molecular mechanisms underlying their association with ROS formation in melanomas. Uveal melanoma (UM), a rare and aggressive eye cancer, has been identified in the TCGA dataset as expressing the highest levels of the superoxide-producing enzyme NADPH oxidase 5 (NOX5) among all human cancers. Our study demonstrates that HDACi treatment increases NOX5 expression in UM cell lines. This upregulation is accompanied by elevated extracellular ROS, which is suppressed when NOX5 is silenced. The use of actinomycin D and cycloheximide significantly reduced HDACi-induced NOX5 expression, suggesting regulation at both transcriptional and translational levels. HDACi treatment also led to accumulation of acetylated histones H3 and H4. Since histone acetylation (particularly H4K5/8/12Ac) recruits BRD4 to facilitate transcription, we evaluated the effect of BRD4 knockdown or exposure to BRD4 inhibitors on NOX5 levels in UM cells. Both approaches reduced NOX5 expression induced by HDACi. Furthermore, dual silencing of the transcription factors Sp1 and Sp3 markedly attenuated both basal and HDACi-induced expression of NOX5. ChIP assays revealed that HDACi treatment increases chromatin-associated acetylated histone H3, phosphorylated RNA polymerase II (p-Ser2), BRD4, Sp1, and Sp3 at the NOX5 promoter region. Collectively, these findings suggest that HDACi-mediated upregulation of NOX5 in UM cells occurs, at least in part, via transcriptional activation of the NOX5 promoter. This process is driven by HDACi-induced histone hyperacetylation, which enhances the recruitment of BRD4, Sp1, and Sp3 to the promoter region, thereby facilitating RNA polymerase II-dependent transcription. Given that HDAC inhibition elevates both NOX5 expression and ROS production, co-targeting HDACs and NOX5 may offer a novel and effective therapeutic strategy in the treatment of UM.", "source_company": "National Cancer Institute", "source_org_type": "研究机构", "row_number": 379, "target_meta": "HDAC", "MOA_meta": "抑制剂"}, {"drug_name": "BET inhibitor", "company": "Chiba University", "org_type": "大学", "target": "BRD2/BRD3/BRD4/BRDT", "modality": "inhibitor", "importance_level": "低", "total_score": 49, "institution_score": 30, "track_score": 70, "milestone_score": 60, "field_heat_score": 65, "bonus_score": 3, "brief_reason": "BET抑制剂靶向BRD蛋白家族，通过抑制杂合ecDNA增强子激活HPV癌基因，在HPV相关口咽癌模型中显示选择性抑制肿瘤生长。该研究来自大学机构，处于preclinical阶段，ecDNA新机制有一定亮点，但非热门靶点且机构非头部药企导致总分较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/2095", "id": "NJ7ECZ0BZznHJdntvNYd", "source_drug_name": "BET inhibitor", "title": "De novo enhancer formation at human-viral junctions drives hybrid extrachromosomal DNA amplification in HPV-associated cancer", "abstract_text": "Introduction: Extrachromosomal DNA (ecDNA) contributes to oncogene amplification in human cancers, yet the mechanisms underlying the formation and function of human-viral hybrid ecDNA (hybrid ecDNA), circular elements harboring both HPV and human sequences, remain unclear. We recently identified hybrid ecDNA in human papillomavirus-associated oropharyngeal cancer (HPVOPC), a rapidly increasing malignancy. Here, we show that de novo enhancer formation at viral-human junctions activates viral oncogenes and promotes hybrid ecDNA self-amplification, revealing a tractable therapeutic vulnerability.\nMethods: Hybrid ecDNA was identified in HPVOPC cell lines and patient-derived xenografts (PDX) using whole-genome sequencing and AmpliconArchitect. Validation was performed by multicolor FISH. Chromatin accessibility and enhancer activity were profiled by ATAC-seq and H3K27ac ChIP-seq. Hi-C sequencing was used to assess 3D chromatin interactions and potential contacts among distinct ecDNA species. Functional significance was evaluated by CRISPR interference (CRISPRi) targeting ecDNA-derived enhancers. Therapeutic relevance was assessed by BET inhibition in vitro and in vivo.\nResults: Hybrid ecDNA was detected in both cell lines and PDX tumors and validated by overlapping human and HPV FISH signals. Epigenomic profiling revealed de novo active enhancers flanking HPV sequences exclusively in hybrid ecDNA(+) tumors. Hi-C demonstrated enhancer-promoter loops linking host enhancers to HPV oncogenes. CRISPRi targeting these enhancers significantly inhibited proliferation in hybrid ecDNA(+) models only (P = 0.006). BET inhibition selectively suppressed hybrid ecDNA(+) tumor growth in vivo (P = 2×10⁻⁵). Importantly, Hi-C contacts also indicated enriched interaction patterns among distinct ecDNA species, suggesting potential extrachromosomal cooperation that enhances viral oncogene expression.\nConclusions: Hybrid ecDNA is a functionally critical structure in HPVOPC by generating de novo enhancers and reorganizing chromatin interactions to activate viral oncogenes, creating a therapeutic vulnerability. Contact enrichment among distinct ecDNA species further suggests participation in a broader extrachromosomal regulatory network in HPV-driven malignancies.", "source_company": "Chiba University", "source_org_type": "大学", "row_number": 398, "target_meta": "BRD2,BRD3,BRD4,BRDT", "MOA_meta": "抑制剂"}, {"drug_name": "scfDNA-PEI nanoparticles", "company": "Mayo Clinic", "org_type": "医院", "target": "cGAS", "modality": "other", "importance_level": "低", "total_score": 49, "institution_score": 35, "track_score": 75, "milestone_score": 45, "field_heat_score": 65, "bonus_score": 2, "brief_reason": "药物通过scfDNA-PEI纳米粒模拟胎儿cfDNA激活cGAS-STING通路，实现单核/巨噬细胞促炎重编程，用于肿瘤免疫治疗概念验证。机构为医院非商业研发、处于早期体外POC阶段、modality非主流热门赛道导致总体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5459", "id": "oFXM_5wBX1NQZOEH-LG6", "source_drug_name": "scfDNA-PEI nanoparticles", "title": "Pregnancy-inspired DNA nanocarriers reproduce a cGAS-driven pro-inflammatory monocyte phenotype", "abstract_text": "Introduction: Placental cell-free DNA (cfDNA) activates maternal monocytes to a proinflammatory phenotype through cGAS-STING signaling during pregnancy, thereby stimulating T cells. We sought to engineer DNA nanocarriers that reproduce this mechanism in human monocytes using clinically translatable materials as a strategy for tumor-associated macrophage (TAM) reprogramming.\nMethods:  A synthetic mimic of fetal cfDNA (scfDNA) was designed, commercially synthesized, and complexed with polyethylenimine (PEI) to form scfDNA-PEI nanoparticles (scfDNA-PEI-NPs) for cytosolic delivery. THP-1 Dual reporter monocytes expressing interferon regulatory factor (IRF)-inducible luciferase were treated with scfDNA-PEI-NPs or human cytotrophoblast derived cfDNA (CTB-DNA) to quantify cGAS-STING-IRF activation. Cytotoxicity was assessed by lactate dehydrogenase (LDH) release to define a non-toxic therapeutic window.\nResults:  scfDNA-PEI-NPs triggered robust cGAS-STING-IRF activation in THP-1 monocytes, exceeding CTB-DNA responses. This response was abolished in cGAS-knockout cells and rescued by a cGAS-independent stimulator of the IRF pathway, confirming cGAS specificity of scfDNA-PEI-NPs. Dose-response analysis showed a > 10-fold separation between cGAS-activating and cytotoxic concentrations, establishing a therapeutic window for myeloid-selective cGAS activation.\nConclusions:  These findings provide proof-of-concept that pregnancy-inspired DNA nanocarriers can reproduce fetal cfDNA-driven activation of a proinflammatory monocyte phenotype in vitro. This platform lays the groundwork for future work on macrophage-targeted cGAS activation and proinflammatory reprogramming for tumor immunotherapy development.", "source_company": "Mayo Clinic", "source_org_type": "医院", "row_number": 421, "target_meta": "cGAS", "MOA_meta": "其他"}, {"drug_name": "FGFR inhibitor", "company": "Moffitt Cancer Center", "org_type": "医院", "target": "FGFR", "modality": "inhibitor", "importance_level": "低", "total_score": 49, "institution_score": 30, "track_score": 70, "milestone_score": 60, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "药物为FDA批准的FGFR抑制剂，靶点FGFR，通过阻断FGF19-FGFR信号轴特异性抑制老年小鼠TNBC肺转移中的线粒体适应和转移。该研究来自医院/学术机构，preclinical水平揭示年龄特异性机制和新治疗潜力，但非原创药物开发且未进入临床阶段。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10492", "id": "4VXM_5wBX1NQZOEH-LG6", "source_drug_name": "FGFR inhibitor", "title": "Old age uncovers FGFR-dependent metabolic dependencies in TNBC lung metastasis with therapeutic potential", "abstract_text": "The clinical manifestation of metastasis in a vital organ is the final stage of breast cancer progression, and the main culprit of breast cancer related mortality. This remain especially problematic in the case of triple negative breast cancer (TNBC), the most aggressive type of breast cancer, often diagnosed in its metastatic form and for which chemotherapies are still the major therapeutic option. Typically, TNBC is seen as a disease of younger women, however, 20% of TNBCs occur in patients aged 65 and older, whose prognosis is equally staggering. Unfortunately, due to co-morbidities, tolerability of chemotherapies, as well as severe reduction in quality of life, majority of women above age 65 can’t or decide not to receive chemotherapy ultimately cutting their lives short. Metastatic outgrowth is largely dictated by the ability of TNBC disseminated cancer cells (DCCs) to thrive distal organs and is largely dependent on the physiology of the specific organs. However, how the aging process, a major driver of changes in organismal physiology, affects the interaction between the host organ and TNBC DCCs remains unknown. Here, we adapted several traditional syngeneic models of TNBC metastasis to old mice of different strains and coupled with RNA-seq to unveil molecular adaptations of TNBC DCCs to the aging lung. We show that the changes that occur in the lung with aging drives an increase in mitochondrial fitness in TNBC DCCs, an adaptation that is necessary for metastasis to thrive in the old lung environment. Mechanistically, our data show that the expression of FGF19, a gut hormone not normally expressed in TNBC DCCs, drives this increase in mitochondrial fitness in the old lung through an autocrine signaling axis impinging on activation of FGF-19 cognate receptor family, FGFRs. Inhibition of FGF19-FGFR signaling using an FDA-approved FGFR inhibitor not only blocks the age-induced increase in mitochondrial fitness but also effectively abolishes lung metastasis in old, but not in young, immune competent and immune compromised mice. We traced this to age-specific metastatic adaptation of TNBC lung metastasis to the increase in bile acids, the canonical regulators of FGF19 expression, in the old lung environment. Together, our work demonstrates an important contribution of age-driven metabolic reprogramming of the host to the traits that enable metastasis to thrive in the lung and provides rationale for the use of FDA-approved FGFR inhibitors for the treatment of breast cancer lung metastasis in the most vulnerable of stage IV metastatic TNBC patients, the elderly.", "source_company": "Moffitt Cancer Center", "source_org_type": "医院", "row_number": 466, "target_meta": "FGFR", "MOA_meta": "抑制剂"}, {"drug_name": "a CEA-directed T-cell engager", "company": "Clínica Universidad de Navarra", "org_type": "医院", "target": "CEA", "modality": "TCE", "importance_level": "低", "total_score": 49, "institution_score": 30, "track_score": 85, "milestone_score": 40, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "药物为靶向CEA的T细胞接合剂（TCE），结合FAP靶向4-1BBL三聚体增强T细胞激活，主要用于MSS结直肠癌的体外或动物模型研究。机构为医院/大学类型非商业公司、摘要未公开且无明确临床里程碑导致总体打分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11992", "id": "AFXM_5wBX1NQZOEH-LK6", "source_drug_name": "a CEA-directed T-cell engager", "title": "FAP-targeted 4-1BBL trimeric costimulation amplifies T-cell activation and antitumor efficacy of a CEA-directed T-cell engager in MSS colorectal cancer", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Clínica Universidad de Navarra", "source_org_type": "医院", "row_number": 487, "target_meta": "CEACAM5", "MOA_meta": "其他"}, {"drug_name": "a CEA-directed T-cell engager", "company": "University of Oxford", "org_type": "大学", "target": "CEA", "modality": "TCE", "importance_level": "低", "total_score": 49, "institution_score": 40, "track_score": 85, "milestone_score": 30, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "药品为靶向CEA的T细胞衔接器（TCE），与FAP靶向4-1BBL三聚体联合增强T细胞激活及MSS结直肠癌抗瘤效果；机构为大学学术型，得分较低，赛道TCE+4-1BB共刺激热门但仅preclinical研究且摘要未公开，整体里程碑价值有限。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11992", "id": "AFXM_5wBX1NQZOEH-LK6", "source_drug_name": "a CEA-directed T-cell engager", "title": "FAP-targeted 4-1BBL trimeric costimulation amplifies T-cell activation and antitumor efficacy of a CEA-directed T-cell engager in MSS colorectal cancer", "abstract_text": "Abstract is embargoed at this time.", "source_company": "University of Oxford", "source_org_type": "大学", "row_number": 488, "target_meta": "CEACAM5", "MOA_meta": "其他"}, {"drug_name": "cyclin-dependent kinase inhibitors", "company": "UT MD Anderson Cancer Center", "org_type": "医院", "target": "CDK", "modality": "inhibitor", "importance_level": "低", "total_score": 49, "institution_score": 35, "track_score": 70, "milestone_score": 50, "field_heat_score": 60, "bonus_score": 2, "brief_reason": "药物为广谱CDK抑制剂，靶向细胞周期调控，在ESCC早期肿瘤起始细胞中显示抑制增殖潜力，但仅为药物重定位筛选的候选，未披露具体化合物或专用靶点。机构为顶级癌症中心但属学术医院类型，非商业药企驱动开发，赛道热度中等偏上，开发阶段为preclinical初步验证，整体商业推进价值有限。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/2934", "id": "l1XM_5wBX1NQZOEH-LK6", "source_drug_name": "cyclin-dependent kinase inhibitors", "title": "Single-cell dissection of ESCC identifies targetable cells-of-origin and therapeutic vulnerabilities in early tumorigenesis", "abstract_text": "Identifying the cells of origin is critical for overcoming therapy resistance and improving early intervention strategies in esophageal squamous cell carcinoma (ESCC). Despite advances in genomic profiling and lineage-trajectory studies, the cellular hierarchies and molecular programs that initiate ESCC remain poorly defined. To address this gap, we applied machine-learning-guided single-cell trajectory analysis to carcinogen (4NQO)-induced ESCC, genetically engineered organoid models, and their normal esophageal counterparts, enabling reconstruction of lineage relationships during early tumorigenesis. Integrating these data with gene regulatory network analysis allowed us to pinpoint transcriptional drivers of tumor initiation, and a transcriptome-based drug repurposing strategy identified candidate compounds capable of targeting these early malignant populations. Our multimodal analyses revealed several distinct epithelial clusters that likely act as cells of origin for ESCC, each exhibiting unique stem- or progenitor-like transcriptional states. Regulatory network analysis highlighted activation of key programs, including PRRX2 and CEBPβ, across these initiating populations. In parallel, the drug repurposing screen identified five candidate compounds, four of which were potent cyclin-dependent kinase (CDK) inhibitors. Correspondingly, CDK inhibitors robustly suppressed ESCC cell proliferation, underscoring their therapeutic potential. Together, these findings define the putative cells of origin in ESCC and their core regulatory networks, establishing a single-cell-driven framework that exposes actionable vulnerabilities in tumor-initiating populations.", "source_company": "UT MD Anderson Cancer Center", "source_org_type": "医院", "row_number": 583, "target_meta": "CDK", "MOA_meta": "抑制剂"}, {"drug_name": "W-DB53", "company": "Emory Winship Cancer Institute", "org_type": "研究机构", "target": "OTUD4-CD73 interaction", "modality": "inhibitor", "importance_level": "低", "total_score": 49, "institution_score": 35, "track_score": 65, "milestone_score": 45, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "W-DB53为选择性小分子抑制剂，靶向阻断OTUD4-CD73相互作用以重塑巨噬细胞并改善肥胖TNBC免疫微环境。研究机构来源+仅动物模型阶段导致总体评分偏低，但新型PPI抑制机制及肥胖相关免疫抵抗靶向具有一定创新性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/969", "id": "nFXM_5wBX1NQZOEH-LK6", "source_drug_name": "W-DB53", "title": "Improving therapeutic efficacy by targeting adenosine signaling in obese breast cancers", "abstract_text": "Accumulated adipocytes in obese cancer patients significantly compromise therapeutic efficacy,yet the underlying mechanisms remain largely undefined. Here, we identify an OTUD4-driven proteolyticaxis as a critical regulator of immune suppression in obesity-associated triple-negative breast cancer(TNBC). Hyperactivation of OTUD4 enhances CD73-mediated adenosinergic signaling in cooperationwith TGF-β, establishing an immunosuppressive tumor microenvironment (TME) enriched with TREM2+APOE+ lipid-laden tumor-associated macrophages (LL-TAMs). This adenosine-rich niche promotes LL-TAM polarization toward a CCL2+ IL6+ efferocytic phenotype, collectively dampening cytotoxic T-cellactivity. Spatial and histologic analyses reveal regional co-expression of TGF-β, OTUD4, and CD73 withinimmune-suppressed tumor zones that spatially align with LL-TAM clusters. To therapeutically target thispathway, we developed W-DB53, a selective small-molecule inhibitor that disrupts the OTUD4-CD73interaction, depletes LL-TAMs, restores T-cell infiltration, and synergizes with immune checkpointinhibitors (ICIs) in obese TNBC models. These findings establish W-DB53 as a macrophage-remodelingprotein-protein interaction (PPI) inhibitor that reprograms efferocytosis and overcomes obesity-drivenimmune resistance in TNBC.", "source_company": "Emory Winship Cancer Institute", "source_org_type": "研究机构", "row_number": 584, "target_meta": "OTUD4,CD73", "MOA_meta": "抑制剂"}, {"drug_name": "anti-Ccl3 neutralizing antibody", "company": "City University of Hong Kong", "org_type": "大学", "target": "CCL3", "modality": "neutralizing antibody", "importance_level": "低", "total_score": 49, "institution_score": 35, "track_score": 65, "milestone_score": 55, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "药物为针对CCL3的中和抗体，主要通过阻断Ccl3+肿瘤细胞与IDE+ M2巨噬细胞及CCR3+ CAFs的交互来抑制ESCC免疫平衡期并增强抗肿瘤免疫。机构为大学非商业研发，开发阶段仅限于动物模型体内验证有效，总分偏低故重要性评为低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9574", "id": "r1XM_5wBX1NQZOEH-LK6", "source_drug_name": "anti-Ccl3 neutralizing antibody", "title": "CCL3+ tumor cells orchestrate immune equilibrium and stemness maintenance in ESCC via IDE+ M2 macrophages and CCR3+ CAFs", "abstract_text": "Immune regulation plays a crucial role in tumor occurrence and development, yet the underlying mechanisms remain largely unclear. By constructing a mouse model to track tumor immune status and utilizing single-cell sequencing technology to dissect the interactions between tumor cells and the tumor microenvironment at different stages, we found that ESCC tumor progression undergoes four key phases: ① immune recognition phase (enhanced CXCL10/H2-K1 antigen presentation signaling); ② immune equilibrium phase (enrichment of PD-1 T cells/CD44 dormant tumor cells); ③ immune escape phase (proliferation of PD-L1+ EMT tumor cells); ④ immune suppression phase (dominated by M2 TAMs/Tregs). Cell communication analysis revealed that intercellular interactions in the tumor primarily occur among tumor cells, macrophages, fibroblasts, and T cells, with tumor cells serving as the core regulatory factor. Further GO analysis of tumor cell subtypes showed enrichment in keratin-reinforced type (Cnfn+), enhanced autophagy type (Plk5+), immunosuppressive type (Ccl3+), and metastasis-enhanced type (Krt8+). Among them, Ccl3+ tumor cells are highly enriched in the immune equilibrium phase and interact with Ide M2 macrophages and Ccr3+ CAFs. In vitro co-culture studies confirmed that tumor cells overexpressing Ccl3 can regulate macrophage polarization toward M2 and promote T cell exhaustion; however, these functions no longer change after knocking down the Ide gene in macrophages. On the other hand, when tumor cells overexpressing Ccl3 are co-cultured with Ccr3-knockout CAFs and control CAFs, the control group significantly enhances the stemness of Ccl3+ tumor cells. These studies confirm that Ccl3+ tumor cells remodel the tumor microenvironment through Ide M2 macrophages and Ccr3+ fibroblasts, thereby regulating stemness and surviving in the immune equilibrium phase. In vivo, neutralizing antibodies targeting Ccl3 effectively inhibit subcutaneous tumor formation and enhance immune effects. This study reveals the key regulatory role of Ccl3 in the immune evolution of ESCC tumors, providing an important molecular basis and potential clinical strategies for overcoming immunotherapy resistance and developing novel targeted therapies.", "source_company": "City University of Hong Kong\ncity university of hong kong", "source_org_type": "大学", "row_number": 601, "target_meta": "CCL3", "MOA_meta": "抗体"}, {"drug_name": "anti-PD-1 antibody", "company": "HD Biosciences, Inc.", "org_type": "公司", "target": "PD-1", "modality": "inhibitor", "importance_level": "低", "total_score": 49, "institution_score": 45, "track_score": 85, "milestone_score": 25, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "药物为抗PD-1抗体，靶点PD-1在免疫治疗领域热度很高，但本条仅为工具性抗体用于同步肿瘤模型研究，未披露任何新型药物或开发进展。机构为CRO服务公司而非drug developer导致总体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1540", "id": "sFXM_5wBX1NQZOEH-LK6", "source_drug_name": "anti-PD-1 antibody", "title": "Synchronously implanted cold tumor abrogates anti-PD-1 response of hot tumor in a syngeneic mouse model", "abstract_text": "Background and Objective: Synchronous cancer describes a new or second primary cancer that develops at the same time as the first primary cancer, either in the same organ or in a different organ with the same molecular basis. Synchronous cancer is not considered metastatic relapse. The prevalence of synchronous cancer varies depending on the cancer type, but overall, it is a rare event occurring in 4.5% to 11.7% of patients with multiple primary malignancies. The impact of a second primary tumor on the progression and treatment response of the first tumor remains poorly understood. This study investigates the interaction between two distinct primary tumors- MC38 colorectal cancer and LL/2 lung cancer- in a synchronous syngeneic mouse model. Specifically, we evaluated how the presence of LL/2 tumor influences the efficacy of anti-PD-1 immunotherapy against MC38 tumor. Changes in immune cell population and cytokine profiles in circulation and within the MC38 tumor microenvironment were also examined. These findings shed light on how inter-tumoral communication affects therapeutic efficacy in the presence of synchronous malignancies.\nMethod and Result: C57BL/6 mice were inoculated subcutaneously with 5 x 105 MC38 cells on the right flank. Mice in group 1 and 3 received an additional MC38 inoculation on the left flank, while group 2 and 4 received 5 x 105 LL/2 cells at the left flank. When MC38 tumor reached approximately 100 mm3, mice were treated with 10 mg/kg of anti-PD-1 antibody intraperitoneally every 4 days. Tumor growth, body weights, immune cell populations, and cytokine levels in blood and tumor tissues were assessed after 10 days of treatment. The body weights of the mice remained no significant differences between groups. Interestingly, although the tumor volumes in group 2 were only slightly higher than in group 2, the tumor volumes in group 4 were significantly higher than in group 3, indicating the presence of LL/2 tumor greatly impaired the efficacy of anti-PD-1 immunotherapy against MC38 tumor. FACS analysis and cytokine analysis confirmed the changes of immune profiling that led to the insensitive of MC38 tumor to the immunotherapy.\nConclusion: The presence of a second primary cancer can profoundly affect the immune checkpoint inhibitor therapeutic response of the first primary tumor through inter-tumoral immune modulation. These findings emphasize the importance of evaluating tumor-tumor communication when designing treatment strategies for patients with synchronous cancer. WuXi AppTec Biology-IVPU offers bilateral tumors models and comprehensive in vivo capability for preclinical oncology drug efficacy studies.", "source_company": "HD Biosciences, Inc.", "source_org_type": "公司", "row_number": 602, "target_meta": "PD1", "MOA_meta": "抑制剂"}, {"drug_name": "FSL-1", "company": "National Institutes of Health", "org_type": "研究机构", "target": "TLR2/6", "modality": "other", "importance_level": "低", "total_score": 49, "institution_score": 45, "track_score": 65, "milestone_score": 35, "field_heat_score": 50, "bonus_score": 0, "brief_reason": "FSL-1为TLR2/6激动剂，通过EV共递送与TGF-βRI抑制剂联用重编程巨噬细胞治疗SCLC肝转移。机构为NIH研究性质而非商业公司、仅动物体内实验无临床推进、赛道为免疫递送+TLR激动剂非当前最热靶点，导致总分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6395", "id": "tlXM_5wBX1NQZOEH-LK6", "source_drug_name": "FSL-1", "title": "Extracellular vesicle-mediated co-delivery of FSL-1 and LY2157299 for immunotherapy of small-cell lung cancer liver metastases", "abstract_text": "Small-cell lung cancer (SCLC) frequently metastasizes to the liver, where macrophage‑dominated immunosuppression sustains tumor outgrowth. Bioinformatic analyses of SCLC liver metastases implicate macrophage metabolism as a driver of hepatic progression. We engineered extracellular vesicles (EVs) co‑delivering FSL‑1 (TLR2/6 agonist) and LY2157299/galunisertib (TGF‑βRI inhibitor) to reprogram macrophages. In vitro, dual‑loaded EVs more efficiently shifted macrophages toward pro‑inflammatory, antigen‑presenting states. In vivo, EVs efficiently targeted intrahepatic tumor sites, decreased liver tumor growth, and prolonged mouse survival. These data support EV‑mediated co‑delivery of FSL‑1 and LY2157299 as a macrophage‑centric strategy for SCLC liver metastasis.", "source_company": "National Institutes of Health", "source_org_type": "研究机构", "row_number": 605, "target_meta": "TLR2,TLR6", "MOA_meta": "其他"}, {"drug_name": "Robotnikinin", "company": "University of Southern California", "org_type": "大学", "target": "Sonic Hedgehog (Shh)", "modality": "inhibitor", "importance_level": "低", "total_score": 49, "institution_score": 35, "track_score": 75, "milestone_score": 45, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "Robotnikinin为Sonic Hedgehog (Shh)通路的小分子抑制剂（直接结合Shh），在胰腺癌肝转移3D模型中显示可降低器官样生长和吉西他滨耐药，但仅为学术机构preclinical工具化合物验证。机构为大学非商业研发，得分较低；SHH通路在肿瘤中有一定研究热度但非当前最热门赛道，整体开发阶段早期导致总分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8432", "id": "W57ECZ0BZznHJdntvNYd", "source_drug_name": "Robotnikinin", "title": "Fibroblast-derived extracellular vesicles promote organ-specific tumor growth and chemoresistance in pancreatic cancer liver metastasis via ptch2 downregulation", "abstract_text": "Pancreatic ductal adenocarcinoma (PDAC) is the 3rd leading cause of cancer death in USA with a 5-year survival rate of only 13%. Early diagnosis is very difficult and 53% of patients are diagnosed after metastasis has already occurred, with liver being the most frequently affected site. Both primary tumors and metastases have dense desmoplastic stroma, which contributes significantly to chemoresistance. However, the mechanisms by which primary and metastatic fibroblasts influence tumor behavior remain understudied. This study aims to investigate the contributions of fibroblasts-derived extracellular vesicles (EVs) at the primary versus metastatic sites. To achieve this, we developed tunable 3D biomimetic models that replicate aspects of the tumor microenvironment (TME) of primary PDAC and the liver metastatic niche (LMN). We used matched primary PDAC and liver metastatic (LM) organoids derived from the Kras+/LSL-G12D; Trp53+/LSL-R172H; Pdx1-Cre genetically engineered mouse model of PDAC, combined with either primary PDAC or liver fibroblasts. We hypothesized that primary and metastatic site derived fibroblasts possess distinct properties influenced by their different TMEs, that lead to organ-specific effects on tumor growth and chemoresistance. Supporting this hypothesis, fibroblasts enhanced tumor growth and chemoresistance to gemcitabine, only when paired with the organoids from the same site. Fibroblast-derived EVs were identified as critical drivers of this site-specific tumor support. Mechanistically, we found that expression of Ptch2, a tumor suppressor in the Sonic Hedgehog (SHH) signaling pathway, is significantly decreased in organoids exposed to site-matched fibroblasts or their EVs, while EV depletion restores Ptch2 expression. Finally, we pharmacologically modulated the SHH pathway via a small molecule Ptch2 agonist, Robotnikinin, which appeared to reduce organoid growth and chemoresistance in our models, indicating a potential role for SHH pathway targeting. These findings suggest that site-specific fibroblast-derived EVs may carry distinct SHH ligands that differentially interact with Ptch2 in tumor cells of the corresponding site, which is currently under investigation. Taken together, our findings underscore the importance of developing models to elucidate the pivotal role of the organ-specific microenvironment in driving tumor progression. Our tunable 3D biomimetic model faithfully recapitulates the tumor-stroma interactions and provides a platform to evaluate therapeutic strategies aimed at disrupting fibroblast-tumor crosstalk. Defining how SHH signaling contributes to tumor growth and chemoresistance driven by fibroblast-derived EVs in an organ-specific manner can potentially uncover novel therapeutic strategies for targeting the metastatic niche in pancreatic cancer.", "source_company": "University of Southern California", "source_org_type": "大学", "row_number": 676, "target_meta": "SHH", "MOA_meta": "抑制剂"}, {"drug_name": "CpG-6tdGO", "company": "Beckman Research Institute of The City of Hope", "org_type": "研究机构", "target": "TERT", "modality": "other", "importance_level": "低", "total_score": 49, "institution_score": 35, "track_score": 65, "milestone_score": 55, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "CpG-6tdGO为CpG-ODN偶联6tdG的寡核苷酸，通过靶向TLR9+ AML细胞递送TERT底物类似物实现端粒损伤和免疫刺激双重作用。机构为研究机构得分较低，赛道新颖但非主流热门、仅preclinical阶段导致总分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8766", "id": "J1XM_5wBX1NQZOEH-LO6", "source_drug_name": "CpG-6tdGO", "title": "Bi-functional thiopurine-based oligonucleotides for AML cell-targeted telomere damage and immunostimulation", "abstract_text": "Telomerase (TERT) is an enzyme commonly activated in human cancers and critical for maintaining cell survival. TERT expression and activation correlates with more aggressive, treatment-resistant disease, with the highest telomerase activity in relapsed acute myeloid leukemia (AML) patients. Telomerase inhibitors showed promise in preclinical studies on AML leading to leukemic stem cells (LSC) eradication. However, TERT inhibition in cancer cells faced challenges, such as the delayed clinical responses and on-target/off-tumor toxicities to hematopoietic stem cells (HSCs) or to activated T cells that result in cytopenias or immunosuppression, respectively. We previously developed clinically-relevant strategy for targeted delivery of therapeutic molecules into TLR9+ positive myeloid cells, such as AML cells including LSCs, using synthetic CpG oligodeoxynucleotides (CpG-ODNs) as a targeting domain. Here, we report generation of new CpG-conjugates for the delivery of a synthetic TERT substrate, 6-thio-2’-deoxy-guanosine (6tdG) into AML cells. CpG-6tdG oligonucleotides (CpG-6tdGOs) comprise multiple (5-10) 6tdG nucleosides in the 3’ end of CpG-ODN. The CpG-6tdGOs retain serum stability, while allowing for slow release of the 6tdG nucleotides after uptake into target leukemic cells. In vitro, CpG-6tdG-oligonucleotides (CpG-6tdGOs) were selectively cytotoxic to human TLR9+/TERT+ AML cells without affecting activated TLR9—/TERT+ T-cells, HSCs or non-malignant TERT— cells. The liquid chromatography-tandem mass spectrometry (LC-MS/MS) analysis confirmed that 6tdG was effectively incorporated into chromatin of target cancer cells after in vitro and in vivo treatment using CpG-6tdGO. Repeated intravenous injections of CpG-6tdGO, but not 6tdG nucleoside, within days induced cytotoxic effects against xenotransplanted models of primary human AML with diverse genomic background in immunodeficient NSG mice and inhibited leukemia progression. CpG-6tdGO showed enhanced antitumor activity when tested in vivo against syngeneic Cbfb/MYH11/Mpl (CMM) and C1498 mouse AML models. In immunocompetent mice, treatment with CpG-6tdGO induced systemic, cancer cell-selective and CD8 T-cell-mediated antitumor immune responses that were at least partly dependent on TLR9- and STING-mediated signaling in response to CpG-6tdGO-induced cancer cell death. Importantly, the repeated treatments were well-tolerated in humanized hCD34/NOG mice. Except for the reduced percentage of human B-cells, CpG-6tdGO did not decrease the numbers of HSCs, myeloid cells, or T-cells. Overall, CpG-6tdGO offers an effective and safer strategy against aggressive TERT+ hematologic malignancies and potentially certain solid tumors.", "source_company": "Beckman Research Institute of The City of Hope", "source_org_type": "研究机构", "row_number": 677, "target_meta": "TERT", "MOA_meta": "其他"}, {"drug_name": "PARP inhibitor", "company": "Shenzhen University", "org_type": "大学", "target": "PARP1", "modality": "inhibitor", "importance_level": "低", "total_score": 49, "institution_score": 35, "track_score": 75, "milestone_score": 45, "field_heat_score": 65, "bonus_score": 0, "brief_reason": "摘要聚焦miR-21-5p通过激活alt-EJ（PARP1、POLQ等）导致OSCC放疗抵抗，PARP抑制剂可逆转抵抗并产生体内协同效应。大学机构分较低，preclinical机制研究清晰但无临床阶段，热门靶点+放疗增敏赛道获得一定赛道分，总分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3981", "id": "N1XM_5wBX1NQZOEH-LO6", "source_drug_name": "PARP inhibitor", "title": "Targeting alternative end-joining overcomes miR-21-5p-mediated radioresistance in oral squamous cell carcinoma", "abstract_text": "Radiation resistance remains a major barrier to effective radiotherapy in oral squamous cell carcinoma (OSCC), yet its molecular basis is incompletely defined. Here, we uncover activation of the alternative end‑joining (alt‑EJ) DNA repair pathway as a key driver of miR‑21‑5p-mediated radioresistance in OSCC. Comprehensive miRNA profiling of radioresistant OSCC clones revealed distinct expression signatures marked by robust upregulation of miR‑21‑5p and miR‑486‑5p, coupled with reduced miR‑320b and miR‑1248. Functional assays, including clonogenic survival and syngeneic mouse tumor models, demonstrated that enforced expression of miR‑21‑5p markedly enhanced radioresistance, accompanied by sustained DNA damage response signaling and improved double‑strand break (DSB) repair capacity. Transcriptomic and genomic analyses of the TCGA‑HNSC cohort revealed that high miR‑21‑5p expression correlates with suppression of canonical DNA repair targets, poor radiotherapy outcomes, elevated tumor mutational burden (TMB), and an increased frequency of microhomology‑mediated insertions/deletions, consistent with heightened alt‑EJ activity. Cross‑validation in independent OSCC datasets and local tumor panels confirmed that miR‑21‑5p-overexpressing tumors exhibit strong activation of alt‑EJ gene programs, including upregulation of PARP1, POLQ, and associated accessory factors. Analysis of diverse cancer cell line databases further established that miR‑21‑5p activity positively correlates with alt‑EJ gene expression independent of microenvironmental influence. Mechanistically, miR‑21‑5p overexpression shifted DSB repair dependence from homologous recombination and classical non‑homologous end‑joining toward alt‑EJ. Pharmacologic or genetic suppression of alt‑EJ components (PARP1 or POLQ) disrupted DSB resolution and effectively restored radiosensitivity in miR‑21‑5p-high OSCC cells. Notably, radiosensitization by PARP inhibition was abrogated in POLQ‑deficient cells, confirming a POLQ‑dependent mechanism. In vivo, miR‑21‑5p-driven OSCC tumors exhibited enhanced expression of alt‑EJ signatures, increased radioresistance, and high TMB. Combination treatment with irradiation and PARP blockade suppressed tumor growth, diminished alt‑EJ gene expression, and prolonged survival in a syngeneic mouse model. Collectively, these findings establish a novel miR‑21‑5p/alt‑EJ signaling axis as a central determinant of radioresistance in OSCC. Targeting alt‑EJ represents a promising therapeutic strategy to overcome miR‑21‑5p-mediated treatment failure and improve radiotherapy efficacy in head and neck cancers.", "source_company": "Shenzhen University", "source_org_type": "大学", "row_number": 690, "target_meta": "PARP1", "MOA_meta": "抑制剂"}, {"drug_name": "anti-PD-1", "company": "Stanford University School of Medicine", "org_type": "大学", "target": "PD-1", "modality": "inhibitor", "importance_level": "低", "total_score": 49, "institution_score": 35, "track_score": 75, "milestone_score": 45, "field_heat_score": 65, "bonus_score": 0, "brief_reason": "anti-PD-1为经典免疫检查点抑制剂，靶向PD-1，GBM小鼠模型中与TTFields联用显示协同免疫激活效应。机构为大学非商业实体、仅动物水平研究且无突破性新机制，导致综合重要性偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5274", "id": "oFXM_5wBX1NQZOEH-LO6", "source_drug_name": "anti-PD-1", "title": "Analyzing Tumor Treating Fields (TTFields) therapy concomitantly with checkpoint inhibitors in a GBM mouse model", "abstract_text": "Glioblastoma (GBM) is the most common malignant form of adult brain tumor, with a median survival of around 1.5-2 years. Despite multimodal treatments (tumor resection, radiotherapy, and chemotherapy) achieving an effective cure remains a significant challenge due to its highly aggressive nature. Immune checkpoint inhibitors have emerged as a promising strategy to combat GBM; however, limitations have hindered clinical success, largely due to the “cold” and immunosuppressive tumor microenvironment (TME). Tumor Treating Fields (TTFields) therapy is a non-invasive, FDA approved treatment for GBM that employs specific frequency ranges (100-500 kHz) delivered through transducer arrays placed on the head. Our initial in vitro studies, using the inovitro system, confirmed that TTFields (72 hours, 200kHz) enhanced the immune response in GBM by inducing immunogenic cell death, which led to the recruitment of immune cells through the release of damage-associated molecular patterns (DAMPs). Additionally, we demonstrated that TTFields increased T-cell activity (IFNγ and perforin) and enhanced the motility and phagocytic activity in antigen presenting cells (Raw 264.7) and dendritic cells (JawsII). We then studied the therapeutic potential of directly applying the TTFields (10-14 days, 200kHz), using the inovivo system, to an orthotopic syngeneic GBM mouse model (CT2A-luciferase) with the checkpoint inhibitor anti-PD-1. Consistent with previous findings, the single arm treatments of TTFields and anti-PD-1 reduced tumor volume and slightly modulated the immune environment. Concomitant treatment of TTFields with systemic anti-PD-1 therapy reduced tumor volume and significantly increased immunomodulation, as observed via an increase in T cells and myeloid cells. Our findings suggest that concomitant treatment of TTFields with checkpoint inhibitors has the potential to help transform GBM into a “hot” tumor, making it an attractive target for immunotherapy.", "source_company": "Stanford University School of Medicine", "source_org_type": "大学", "row_number": 757, "target_meta": "PD1", "MOA_meta": "抑制剂"}, {"drug_name": "iBAP-II", "company": "University of Ulsan College of Medicine, Asan Medical Center", "org_type": "医院", "target": "BAP1", "modality": "inhibitor", "importance_level": "低", "total_score": 49, "institution_score": 35, "track_score": 65, "milestone_score": 45, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "iBAP-II为选择性BAP1小分子抑制剂，通过抑制BAP1去泛素化活性稳定BIRC5以逆转胃癌5-FU耐药。机构为医院学术型、仅细胞水平验证敏感性增强、无公司推进、开发阶段早期导致总分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1956", "id": "t1XM_5wBX1NQZOEH-LO6", "source_drug_name": "iBAP-II", "title": "BAP1 stabilizes BIRC5 to promote chemoresistance in gastric cancer", "abstract_text": "Gastric cancer is a highly aggressive malignancy associated with poor prognosis. 5-Fluorouracil (5FU) is an anticancer drug widely used to treat gastric cancer, however, the development of drug resistance during treatment remains a major clinical challenge. Therefore, understanding the molecular mechanisms underlying 5-FU resistance is essential for improving chemotherapeutic efficacy. The ubiquitin-proteasome system (UPS) is a key regulatory mechanism that controls the stability and function of intracellular proteins, with deubiquitinases (DUBs) serving as important modulators within this pathway. BRCA1-associated protein-1 (BAP1) is a representative DUB that has been implicated in tumorigenesis across various cancers; however, its role in gastric cancer and drug resistance remains poorly understood. In this study, we found that not only BAP1 but also anti-apoptotic protein BIRC5 is expressed at higher levels in 5FU-resistant gastric cancer cells compared to normal gastric cancer cells. We confirmed that BAP1 stabilizes BIRC5, a known anti-apoptotic protein, through deubiquitination. And we identified that knockdown of BAP1 reduced viability, migration, and invasion of gastric cancer cells. Furthermore, reduced BAP1 expression decreased BIRC5 protein expression, and induced apoptosis through the cleavage of PARP and Caspase-3. Notably, treatment with the selective BAP1 inhibitor iBAP-II increased the sensitivity of gastric cancer cells to 5-FU. Our findings revealed that BAP1 enhances 5-FU resistance and promotes gastric cancer progression by stabilizing BIRC5 and highlight BAP1 as a potential therapeutic target to enhance the efficacy of chemotherapy in gastric cancer.", "source_company": "University of Ulsan College of Medicine, Asan Medical Center", "source_org_type": "医院", "row_number": 776, "target_meta": "BAP1", "MOA_meta": "抑制剂"}, {"drug_name": "TfR-1-IN-1", "company": "UT MD Anderson Cancer Center", "org_type": "医院", "target": "TFRC", "modality": "inhibitor", "importance_level": "低", "total_score": 49, "institution_score": 35, "track_score": 65, "milestone_score": 45, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "TfR-1-IN-1为TFRC（转铁蛋白受体1）抑制剂，在ecDNA+胃癌患者来源类器官中显示选择性抑制增殖，与CHK1抑制剂协同作用。机构为医院/学术中心非商业公司、处于功能验证的preclinical早期阶段导致总分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6965", "id": "xVXM_5wBX1NQZOEH-LO6", "source_drug_name": "TfR-1-IN-1", "title": "Combined pan and precision targeting in extrachromosomal DNA-positive gastric cancer", "abstract_text": "Gastric adenocarcinoma (GAC) remains a major health challenge with high mortality due to late diagnosis, therapy resistance, and limited targeted options. Extrachromosomal DNA (ecDNA)—circular DNA elements carrying amplified oncogenes such as MYC, ERBB2, and EGFR—enhances transcriptional output, therapy resistance, and genomic instability. However, its role in GAC is poorly understood, and current models fail to recapitulate patient tumor complexity. Patient-derived organoids (PDOs) preserve tumor-specific features, including ecDNA, providing an ideal platform for mechanistic and therapeutic exploration.We hypothesize that ecDNA drives unique oncogenic programs in GAC that create exploitable vulnerabilities. Analysis of 221 TCGA-STAD samples with AmpliconArchitect identified ecDNA in 33.3% of primary tumors, absent in matched normal blood. ecDNA+ tumors showed distinct amplification patterns, with proteomic profiling revealing CHEK1 and TFRC enrichment, suggesting co-targetable vulnerabilities. To model these tumors, we established a PDO biobank comprising 5 primary and 9 ascites-derived PDOs. ecDNA was detected in 5/9 (55.6%) ascites-derived and 1/5 (20%) primary PDOs, consistent with ecDNA enrichment in metastatic settings. Amplified oncogenes included PTP4A3, for which inhibitors are available.RNA-seq comparison of ecDNA+ PDO 385 with ecDNA- PDOs (4666, 4601) revealed distinct transcriptional programs, with enriched expression on chromosomes 8 and 20. Transcription factor analysis identified MYC, also amplified as ecDNA. Immunofluorescence confirmed higher TFRC, CHEK1, MYC, and PRL3 (PTP4A3) expression and increased Ki67 in ecDNA+ PDO 385, supporting oncogene overexpression and aggressive growth. Drug screening predicted compounds reversing the ecDNA+ signature. Functional assays showed the TFRC inhibitor (TfR-1-IN-1) reduced proliferation of ecDNA+ PDO 385, while CHK1 inhibition had modest effects. Combined TFRC and CHK1 inhibition synergistically suppressed ecDNA+ PDO growth, with minimal effects on ecDNA- controls. These results highlight the selective vulnerability of ecDNA-driven tumors to co-targeting strategies. Using a PDO biobank, we aim to uncover and exploit vulnerabilities in ecDNA-positive GAC.", "source_company": "UT MD Anderson Cancer Center", "source_org_type": "医院", "row_number": 786, "target_meta": "TFRC", "MOA_meta": "抑制剂"}, {"drug_name": "PROTACs", "company": "Massachusetts Institute of Technology", "org_type": "大学", "target": "PAX3::FOXO1", "modality": "PROTAC", "importance_level": "低", "total_score": 49, "institution_score": 35, "track_score": 90, "milestone_score": 25, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "针对罕见儿科癌症融合蛋白PAX3::FOXO1开发PROTAC降解剂，该靶点高度无序且目前无直接治疗药物；PROTAC赛道热度高，但研发机构为大学、项目仍处于早期筛选和工具构建阶段、无细胞活性数据，整体开发进展有限。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6520", "id": "0lXM_5wBX1NQZOEH-LO6", "source_drug_name": "PROTACs", "title": "Non-covalent small molecule probe discovery of large intrinsically disordered protein", "abstract_text": "Fusion-positive alveolar rhabdomyosarcoma (ARMS), is a rare pediatric cancer often characterized by the pathognomonic fusion protein PAX3::FOXO1. Similar to other highly disordered transcription factors, PAX3::FOXO1 lacks typical small-molecule binding pockets thus making drug development difficult by conventional structural oriented design or traditional screening. Currently, there is no direct therapeutic approach to treat children with fusion-positive ARMS and patients are treated with ineffective traditional chemotherapeutic agents. Previously, we screened a library of small molecules against PAX3::FOXO1 via Small-Molecule Microarrays (SMMs) and identified a compound that shows selective target engagement in thermal shift assay but no apparent cellular activity. Furthermore, we are exploring targeted degradation with PROTACs due to the slow turn-over rate of this target. We have identified a scalable protein purification strategy to achieve stable, functional recombinant PAX3::FOXO1 and we are in the process of expanding the SMMs libraries up to 300,000 compounds. To validate hits from those high throughput screenings, we developed lentiviral transduced ARMS cell lines expressing HiBiT-tagged PAX3::FOXO1, enabling plate-based reporter assays as well as thermal shift assays. Small molecules are highly advantageous in their administration, delivery, and patient accessibility. We hope to address some of the unmet needs in the space of small molecule drug discovery against intrinsically disordered oncoprotein and transcription factors.", "source_company": "Massachusetts Institute of Technology", "source_org_type": "大学", "row_number": 799, "target_meta": "PAX3,FOXO1", "MOA_meta": "PROTAC"}, {"drug_name": "bispecific antibody therapy", "company": "Children's Hospital of Philadelphia", "org_type": "医院", "target": "未披露", "modality": "bispecific antibody", "importance_level": "低", "total_score": 49, "institution_score": 40, "track_score": 85, "milestone_score": 30, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "药品为双特异性抗体疗法，用于儿童癌症精准免疫治疗，但摘要无具体内容，未披露靶点和任何开发细节。机构为医院而非药企，开发阶段信息缺失，导致总体里程碑和机构评分较低，尽管双抗赛道热度较高。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/500", "id": "ClXM_5wBX1NQZOEH-LS6", "source_drug_name": "bispecific antibody therapy", "title": "Precision immunotherapy: CAR T-cell and bispecific antibody therapies for childhood cancers", "abstract_text": "There is no abstract associated with this presentation.", "source_company": "Children's Hospital of Philadelphia", "source_org_type": "医院", "row_number": 838, "target_meta": "not available", "MOA_meta": "双特异性抗体"}, {"drug_name": "NCI-006", "company": "National Institutes of Health", "org_type": "研究机构", "target": "LDHA", "modality": "inhibitor", "importance_level": "低", "total_score": 49, "institution_score": 45, "track_score": 65, "milestone_score": 35, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "NCI-006为LDHA抑制剂，旨在通过抑制肿瘤乳酸产生改善TME以增强CAR-T抗肿瘤免疫。机构为NIH非商业顶级研究机构但非药企、仅早期体外+荷瘤小鼠模型无临床阶段进展导致总分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5144", "id": "LlXM_5wBX1NQZOEH-LS6", "source_drug_name": "NCI-006", "title": "Modulating the tumor microenvironment (TME) to enhance anti tumor immunity using metabolic inhibitors", "abstract_text": "The tumor microenvironment (TME) presents a challenging setting for anti-tumor immunity due to its extreme metabolic features: nutrient deprivation, metabolite accumulation, acidity and hypoxia. Immune cells become dysfunctional under these unfavorable conditions resulting in diminished anti-tumor activity. Thus, strategies to address immunosuppressive conditions in the TME are warranted. We utilized metabolic inhibitors to modulate the TME and enhance anti-tumor immune responses. Neuroendocrine tumors (NETs) and chimeric antigen receptor (CAR)-T cells for somatostatin receptor 2 (SSTR2), a potential therapeutic target for NETs, were utilized as our experimental model. SSTR2 CAR-T cells were prepared from CD8+ T cells of healthy donors. To recapitulate T cell dysfunction in TME, CAR-T cells were cultured under unfavorable metabolic situations: acidic, hypoxic and low glucose conditions. The CAR-T cells exhibited dysfunctional phenotypes including decreased proliferation and viability and impaired cytotoxicity and cytokine production capacity. Additionally, exhaustion-related markers were significantly upregulated on CAR-T cells especially under acidic conditions. To modulate metabolism of NETs, we utilized inhibitors targeting lactate dehydrogenase A (LDHA) and mitochondrial complex I. LDH inhibitor NCI-006 reduced glucose consumption and lactate (Lac) production from NETs by inhibiting lactate fermentation, resulting in reduced extracellular acidification. However, NETs exhibited metabolic rewiring to oxidative phosphorylation (OXPHOS) after NCI-006 treatment. In contrast, Complex I inhibitor IACS-010759 treatment induced OXPHOS inhibition and rewiring to aerobic glycolysis. Combined treatment with these inhibitors successfully interrupted metabolic rewiring of NETs by blocking both aerobic glycolysis and OXPHOS. Hyperpolarized magnetic resonance imaging (HP-MRI) with 1-13C pyruvate (Pyr) and electron paramagnetic resonance (EPR) pO2 imaging were conducted to monitor in vivo metabolic activities in NET-derived xenograft tumors. Consistent to our in vitro findings, NCI-006 suppressed Lac production from Pyr, and IACS-010759 treatment resulted in elevated pO2 level in xenograft tumors. However, metabolic rewiring was also observed in xenograft model; NCI-006 treatment exacerbated hypoxia and IACS-010759 promoted Lac production from Pyr. To overcome the metabolic rewiring, we attempted combination treatment with NCI-006 and IACS-010759 on xenograft mice. The combination treatment effectively abrogated metabolic flexibility of NET-derived xenograft tumors. Metabolic stress resulted in CAR-T cell dysfunction, while NCI-006 and IACS-010759 showed potential to improve the extracellular environment of the TME. Further studies are warranted to test the feasibility and efficacy of metabolic inhibitors in combination with CAR-T therapy.", "source_company": "National Institutes of Health", "source_org_type": "研究机构", "row_number": 864, "target_meta": "LDHA", "MOA_meta": "抑制剂"}, {"drug_name": "h6E6", "company": "University of California, San Diego", "org_type": "大学", "target": "ROR2", "modality": "monoclonal antibody", "importance_level": "低", "total_score": 49, "institution_score": 35, "track_score": 65, "milestone_score": 55, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "h6E6为针对ROR2的高亲和力人源化单抗，可阻断ROR2信号，在TNBC干细胞模型中显示协同APR-246逆转干性和耐药潜力。机构为大学非商业化早期研究，preclinical数据扎实但无临床进展，ROR2在实体瘤尤其是TNBC有一定新兴靶点价值但非最热门赛道，导致总分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4580", "id": "MVXM_5wBX1NQZOEH-LS6", "source_drug_name": "h6E6", "title": "Anti-ROR2 therapies target cancer stem cells in triple-negative breast cancer", "abstract_text": "ROR1 and ROR2 are developmentally restricted, structurally related cell surface proteins expressed during embryogenesis but absent in adult tissues. Many cancers, including breast cancer, aberrantly express ROR1/ROR2. We hypothesize that ROR1 and ROR2 mark triple-negative breast cancer (TNBC) stem cells (CSCs) and mediate cancer stemness, epithelial-mesenchymal transition (EMT), metastasis, and resistance to reactive oxygen species (ROS) triggered by radiation or chemotherapy via ROR1/ROR2 signaling. Patient-derived xenografts (PDX) in immunodeficient NOD-scid gamma (NSG) mice (N=7) enabled direct comparison of TNBC tissue and early-passage (T1) PDX using oligonucleotide-barcoded antibodies and single-cell RNA-seq. PDX retained high proportions of ROR2+ TNBC cells with variable or absent ROR1. ROR2+ cell abundance in T1 PDX matched biopsy and showed enriched stemness, EMT, and upregulated ERK1/2, NF-κB, NRF2 target genes (FDR<0.0001). Extreme limiting dilution assays showed 1,000 or 50,000 ROR2+, but not ROR2-negative, cells, formed secondary PDX tumors (p<0.0001). APR-246, an investigational anti-cancer agent, promotes cell death via p53 restoration/ROS generation. We generated a high-affinity, humanized monoclonal antibody (mAb) specific for human ROR2 (h6E6) that could block ROR2 signaling, analogous to the capacity of our previous anti-ROR1 mAb (zilovertamab) to block ROR1 signaling. Observing that the vast majority of ROR1+ TNBC co-express ROR2, we hypothesized that targeting ROR2+ TNBC cells with h6E6 mAb could synergize with APR-246 to reverse CSC properties, inhibit PDX engraftment, and overcome resistance to oxidative stress induced by therapy. In vitro, h6E6 treatment enhanced TNBC PDX cell sensitivity to APR-246 versus isotype control (hIgG1) (p<0.005). In NSG mice with ROR2+ TNBC PDX, intravenous h6E6, compared to control hIgG1, reduced expression of cancer stemness and EMT genes, as well as ERK1/2, NF-κB, and NRF2 pathway targets (FDR<0.0001), and caused a 5-fold reduction in NQO1, the main NRF2 downstream target, and increased sensitivity to APR-246 (p<0.001). By integrating rigorous experimental controls in both in vitro and in vivo studies using early-passage PDX, our work demonstrates that anti-ROR2 antibody therapy, combined with redox-modulating agents like APR-246, can effectively target CSC-driven disease persistence and therapy resistance in TNBC, supporting future clinical trials of h6E6 targeting ROR2+ TNBC.", "source_company": "University of California, San Diego", "source_org_type": "大学", "row_number": 867, "target_meta": "ROR2", "MOA_meta": "单抗"}, {"drug_name": "redirected cytomegalovirus immunity", "company": "University California San Diego", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 49, "institution_score": 40, "track_score": 75, "milestone_score": 30, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "该项目利用预存的巨细胞病毒（CMV）免疫记忆，通过重定向CMV特异性T细胞攻击乳腺肿瘤，属于创新的病毒免疫重定向免疫疗法，但靶点和具体机制未披露。机构为大学，开发阶段为preclinical且摘要被禁，综合热度一般导致总分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11537", "id": "cZ7ECZ0BZznHJdntvNYd", "source_drug_name": "redirected cytomegalovirus immunity", "title": "Redirecting cytomegalovirus immunity against breast tumors for immunotherapy", "abstract_text": "Abstract is embargoed at this time.", "source_company": "University California San Diego", "source_org_type": "大学", "row_number": 885, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "HIF2a targeting", "company": "UT MD Anderson Cancer Center", "org_type": "医院", "target": "HIF2a", "modality": "inhibitor", "importance_level": "低", "total_score": 49, "institution_score": 40, "track_score": 85, "milestone_score": 30, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "药物靶向HIF2α，主要用于Von Hippel-Lindau综合征相关肿瘤，该靶点在ccRCC领域已有批准药物belzutifan。机构为医院/学术中心，无明确公司开发或临床里程碑信息，导致整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/213", "id": "qlXM_5wBX1NQZOEH-LS6", "source_drug_name": "HIF2a targeting", "title": "A paradigm shift in Von Hippel Lindau Syndrome through HIF2a targeting", "abstract_text": "There is no abstract associated with this presentation.", "source_company": "UT MD Anderson Cancer Center", "source_org_type": "医院", "row_number": 956, "target_meta": "HIF-2α", "MOA_meta": "抑制剂"}, {"drug_name": "HER2 CAR T-cells", "company": "Axion BioSystems", "org_type": "公司", "target": "HER2", "modality": "CAR", "importance_level": "低", "total_score": 49, "institution_score": 40, "track_score": 85, "milestone_score": 30, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "HER2 CAR-T针对HER2靶点，属于细胞治疗热门赛道，但Axion BioSystems作为仪器工具提供商而非药物研发公司，摘要仅展示其Omni平台用于HER2 CAR-T体外杀伤力测试，无药物自身开发里程碑。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9370", "id": "s1XM_5wBX1NQZOEH-LS6", "source_drug_name": "HER2 CAR T-cells", "title": "Fluorescence potency assays for evaluating HER2 CAR T-cell-mediated killing in cancer cells", "abstract_text": "Introduction Harnessing the potent cytotoxicity of chimeric antigen receptor T (CAR-T) cells has revolutionized cancer immunotherapy. A key factor influencing CAR-T cell efficacy is target antigen density on cancer cells. Human epidermal growth factor receptor 2 (HER2), overexpressed in various cancers like ovarian and lung carcinomas, is a promising target for CAR-T cell therapy. Traditional cytotoxicity assays generally provide only static endpoint measurements and often rely on 2D cell culture models, which fail to capture the structural complexity of tumors in vivo—a factor crucial to CAR-T cell efficacy. Live-cell imaging offers a solution by enabling non-invasive, real-time monitoring of cytotoxicity. Therefore, this study aims to explore the dynamics of CAR-T cell-mediated cytotoxicity against cancer cells with varying HER2 expression levels, comparing outcomes between 2D and 3D cell culture models using the Omni platform by Axion BioSystems. Methods Monolayers and spheroids of SKOV3 (ovarian carcinoma) and A549 (lung adenocarcinoma) cells, tagged with GFP, were exposed to HER2 CAR-T cells at different Effector:Target (E:T) ratios. Using the Omni platform, hourly brightfield and fluorescent images were captured over 72 hours to assess cancer cell growth and cytotoxicity and quantify the cytolysis of fluorescent target cells. Percent cytolysis of the target cells was calculated by comparing the green fluorescent intensity of treated wells to no treatment control wells. Results As expected, A549 cells treated with CAR T-cells exhibited dose-dependent decrease in fluorescence confluency (%), with near-complete cell lysis observed in the 5:1 E:T ratio group at 160 hours. Immune cell-mediated killing was assessed by applying HER2-targeted CAR T-cells to both SKOV3-GFP and A549-GFP spheroids. SKOV3-GFP spheroids treated with CAR T-cells showed a dose-dependent decrease in fluorescence intensity, with higher E:T ratios (2:1, 5:1, and 10:1) resulting in approximately 75% reduction in fluorescence intensity by 72 hours. In contrast, A549 spheroids only exhibited significant killing at 5:1 and 10:1 E:T ratios, while minimal decreases in intensity were observed at other ratios. Conclusion The Omni platform enables real-time monitoring of CAR T-cell interactions with target cells, providing key insights into the cytotoxic potential of these engineered immune cells. Fluorescent metrics were used to track immune cell-mediated killing, with changes in fluorescence confluency and intensity reflecting the extent of target cell death. Results showed that the potency of CAR T-cell-mediated cytolysis was dose-dependent, with higher E:T ratios leading to greater target cell killing. SKOV3-GFP spheroids, which overexpress HER2, were more susceptible to HER2 CAR T-cell-mediated killing, while A549-GFP spheroids with low HER2 expression required higher E:T ratios for effective cytolysis.", "source_company": "Axion BioSystems", "source_org_type": "公司", "row_number": 964, "target_meta": "HER2", "MOA_meta": "其他"}, {"drug_name": "magnetoelectric metal-organic frameworks", "company": "National Tsing Hua University", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 49, "institution_score": 35, "track_score": 75, "milestone_score": 40, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "该材料为磁电金属有机框架，通过电磁场调控铁 redox 状态诱导铁死亡并激活免疫，用于胶质母细胞瘤治疗，靶点未明确披露。大学机构分数较低，但铁死亡+免疫增强+诊断治疗一体化在脑瘤领域有一定创新热度，整体仍处于概念验证阶段。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6390", "id": "OJ7M_5wBZznHJdnt_W3O", "source_drug_name": "magnetoelectric metal-organic frameworks", "title": "Magnetoelectric MOFs for ferroptosis-driven and immune-enhanced glioblastoma therapy", "abstract_text": "This study explores the innovative application of magnetoelectric metal-organic frameworks (MOFs) for inducing ferroptosis in glioblastoma (GBM), aiming to transform both therapeutic precision and diagnostic efficacy. MOFs, with their tunable chemical and physical properties, serve as versatile platforms for precision oncology. Here, magnetoelectric MOFs are engineered to harness electromagnetic fields, regulating intracellular iron redox states to elevate reactive oxygen species (ROS) production and drive lipid peroxidation—the hallmark of ferroptosis, a distinct iron-dependent form of programmed cell death.To enhance tumor specificity, these MOFs are conjugated with extracellular vesicles (EVs), enabling selective delivery to GBM cells and minimizing off-target toxicity. This targeted system not only improves therapeutic efficacy but also reduces side effects. Moreover, the magnetoelectric MOFs are MRI-compatible, allowing real-time tumor imaging and precise localization. This dual diagnostic-therapeutic capacity offers a powerful, non-invasive treatment strategy.Beyond direct cytotoxicity, MOF-induced ferroptosis promotes the release of tumor-associated antigens, triggering immune activation and potentially initiating immunogenic cell death (ICD). This immunomodulatory effect broadens therapeutic benefit by reshaping the tumor microenvironment. Collectively, this multifunctional MOF-based platform integrates diagnostics, therapy, and immunogenic modulation, representing a paradigm shift for treating one of the most aggressive and therapy-resistant cancers.", "source_company": "National Tsing Hua University", "source_org_type": "大学", "row_number": 986, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "anti-PD-1 antibody", "company": "Seoul National University", "org_type": "大学", "target": "PD-1", "modality": "inhibitor", "importance_level": "低", "total_score": 49, "institution_score": 35, "track_score": 75, "milestone_score": 40, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "摘要聚焦肿瘤内源IRE1α信号通过上调PD-L1和重塑TME介导免疫逃逸和抗PD-1耐药，提出IRE1α抑制剂联合anti-PD-1的策略，但未披露新型anti-PD-1药物本身信息，仅涉及现有anti-PD-1抗体。机构为大学、处于机制研究阶段、无药物开发里程碑导致总体评分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5262", "id": "V57M_5wBZznHJdnt_W3O", "source_drug_name": "anti-PD-1 antibody", "title": "Tumor-intrinsic IRE1α signaling drives immune evasion and resistance to immune checkpoint inhibitor in lung cancer by upregulating PD-L1 and remodeling the tumor microenvironment", "abstract_text": "Tumor cells exploit endoplasmic reticulum (ER) stress pathways for survival. While the role of the unfolded protein response in tumorigenesis is well-established, its specific effect on the tumor microenvironment (TME) and therapeutic resistance in non-small cell lung cancer (NSCLC), particularly via IRE1α signaling, remains poorly understood. Here, we demonstrate that high IRE1α activity correlates with poor prognosis and resistance to immune checkpoint inhibitors in NSCLC patients. IRE1α activation was associated with an immunosuppressive TME, characterized by enriched regulatory T-cell (Treg) and M2-like tumor-associated macrophage (TAM) signatures in patient cohorts. Consistently, genetic ablation of tumor-intrinsic IRE1α (ERN1 KO) in immunocompetent mice significantly attenuated tumor growth and enhanced CD8+ T-cell infiltration. Mechanistically, IRE1α promoted the expression and secretion of key chemokines, specifically CCL20, which in turn drove M2-like macrophage differentiation in vitro. Notably, this pro-tumorigenic secretome was abrogated by the IRE1α inhibitor MKC8866. Concurrently, IRE1α-XBP1s signaling synergized with IFNγ to directly upregulate tumor-intrinsic PD-L1 expression. This process was mediated by the activation of the RIG-I-IRF1 axis, sustained STAT1 phosphorylation, and direct XBP1s binding to the CD274 promoter. Collectively, tumor-intrinsic IRE1α orchestrates immune evasion in NSCLC by amplifying tumor-intrinsic PD-L1 expression through the IFNγ-STAT1-XBP1s-IRF1 axis and remodeling the TME via chemokines such as CCL20 that recruit immunosuppressive cell populations. The combination of an IRE1α inhibitor and anti-PD-1 antibody represents a promising strategy to enhance the efficacy of immunotherapy for NSCLC.", "source_company": "Seoul National University", "source_org_type": "大学", "row_number": 1010, "target_meta": "PD1", "MOA_meta": "抑制剂"}, {"drug_name": "nanoscintillator-based photosensitizer", "company": "Sunnybrook Health Sciences Centre", "org_type": "医院", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 49, "institution_score": 35, "track_score": 75, "milestone_score": 45, "field_heat_score": 65, "bonus_score": 3, "brief_reason": "基于纳米闪烁体激发的光敏剂实现X射线激活的光动力疗法（radioPDT），无需受体靶向，适用于异质性肿瘤如胶质母细胞瘤。机构为医院而非药企、仍处preclinical模型验证阶段导致总分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6289", "id": "a57M_5wBZznHJdnt_W3O", "source_drug_name": "nanoscintillator-based photosensitizer", "title": "Biophysical enhancement of radiation-activated photodynamic therapy (radioPDT) and translational brain tumor models", "abstract_text": "Background: Radiation-activated photodynamic therapy (radioPDT) uses X-ray-excited nanoscintillators to activate photosensitizers deep within tissues, generating cytotoxic reactive oxygen species without requiring receptor expression. This biophysical strategy is well suited for heterogeneous tumors such as glioblastoma (GBM), where receptor-targeted approaches often fail. A major translational barrier is the blood-brain barrier (BBB), which restricts nanoparticle entry. Physical modulation via focused ultrasound (FUS) and microbubble cavitation can enhance nanoparticle delivery and potentially improve radioPDT efficacy. To evaluate this approach, we established a multi-model pipeline incorporating flank xenografts, intracranial GBM models, and the chick CAM system, allowing visualization of nanoparticle transport, vascular effects, and treatment response.\nMethods: SCID mice bearing PC3 flank tumors received control, radiation, FUS, NP+RAD, NP+FUS+RAD, or NP+microbubbles+FUS+RAD. Tumors were analyzed using multiplex immunofluorescence for proliferation/apoptosis (Ki67, cleaved Caspase-3), DNA damage (γ-H2AX, 53BP1), oxidative injury (4-HNE, TUNEL), vascular structure (CD31, NG2), hypoxia (CA9, HIF-1α), and inflammation (CD45, Iba1). For translational studies, U87 and U251 GBM cells expressing LUC-GFP were validated and used to generate intracranial xenografts for bioluminescence imaging and a CAM model enabling rapid assessment of nanoparticle behavior and radioPDT effects.\nResults: radioPDT alone disrupted endothelial cells, while radioPDT combined with microbubble-enhanced FUS produced both endothelial and pericyte disruption, suggesting potential for BBB modulation. Multiplex tumor analysis is ongoing. LUC-GFP GBM models have been established, and intracranial and CAM tumors provide complementary systems to study FUS-mediated BBB opening and nanoparticle delivery during radioPDT.\nConclusions: radioPDT may amplify ultrasound-mediated vascular modulation without requiring receptor-specific targeting. The integrated PC3, intracranial GBM, and CAM platforms establish a translational pathway to evaluate BBB-penetrant, physics-based radioPDT. These studies are designed to define how physical forces—rather than receptor-mediated uptake—shape nanoparticle distribution, vascular response, DNA damage, oxidative injury, and overall radioPDT potency.", "source_company": "Sunnybrook Health Sciences Centre", "source_org_type": "医院", "row_number": 1021, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "IDH inhibitor", "company": "The Hospital for Sick Children", "org_type": "医院", "target": "IDH1", "modality": "inhibitor", "importance_level": "低", "total_score": 49, "institution_score": 30, "track_score": 70, "milestone_score": 70, "field_heat_score": 60, "bonus_score": 5, "brief_reason": "药物为IDH抑制剂，靶向IDH1突变，主要在儿童医院开展的转物种研究显示联合ICI治疗MMRD-mIDH胶质瘤有初步临床应答和生存改善。机构为医院非商业公司导致institution_score较低，尽管赛道热门且有组合疗法里程碑，但总体分数偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1811", "id": "jp7M_5wBZznHJdnt_W3O", "source_drug_name": "IDH inhibitor", "title": "Trans-species analysis of mismatch repair deficient IDH1 mutant gliomas reveals a unique genomic and immune landscape resulting in favorable response to combination immune and targeted therapy", "abstract_text": "High-grade gliomas are deadly tumors in children and young adults (CAYA). Mismatch Repair Deficiency (MMRD) is present in 5-10% of CAYA gliomas and is typically associated with favorable response to immune checkpoint inhibitors (ICI). Interestingly, a subset of MMRD-CAYA gliomas harboring IDH1 mutations fails to respond to ICI. At the molecular level, the interaction of MMRD with mutant IDH (mIDH) and the causes of ICI resistance are not well understood.\nTo tackle this challenge and develop effective therapeutic strategies for these cancers, we performed trans-species clinical, multi-omic, and immune analysis of human and murine tumors.\nMolecularly, MMRD-mIDH gliomas displayed a profile resembling mismatch repair proficient (MMRP) astrocytomas, characterized by frequent TP53 (83%) and ATRX (76%) mutations and absence of oligodendroglioma-associated alterations (1p/19q codeletion). Nevertheless, in contrast to MMRP-mIDH gliomas, which more commonly present as low-grade tumors, >91% of MMRD-mIDH gliomas were high-grade, exhibiting significantly worse outcomes (p<0.001). Compared with MMRD-IDH wildtype gliomas, MMRD-mIDH gliomas exhibited reduced tumor mutation burden (TMB, 113 vs 28 mutations/Mb, p<0.05) and immune infiltration, quantified by Tumor Inflammation Signature and CD8+ T cell density, partially explaining their inferior survival under ICI treatment.\nIn order to study tumor development, metabolic and immune profiles, as well as response to combination therapy, we developed a novel MMRD-mIDH glioma mouse model (Olig2-Cre+/Msh2LoxP/LoxP/Trp53LoxP/LoxP/LSL-Idh1R132H/+). Mouse MMRD-mIDH gliomas displayed characteristic features of human gliomas, including TMB (20 mutations/Mb), altered glioma driver genes (ATRX, NF1), diffuse cerebral involvement, and low immune infiltrates (p<0.05) as compared with MMRD-IDH wildtype models. Preliminary data reveals that mIDH inhibition does not impact proliferative and stemness capacity of MMRD-mIDH mouse glioma cells in vitro, while detailed analysis of the effect of mIDH inhibition on genomic, transcriptomic, and immune profiles are ongoing.\nStrikingly, informed by our trans-species analysis, an initial trial using the addition of IDH inhibitor to ICI (n=13 patients) led to objective radiological responses and prolonged survival at 12-months compared to ICI monotherapy (p=0.01).\nMMRD-mIDH gliomas are a genetically and biologically distinct group of tumors with limited therapeutic options. Molecular and immune profiling of MMRD-mIDH gliomas, from both patients and a novel mouse model, enables investigation of the biology underlying glioma development and testing of improved therapeutic approaches.", "source_company": "The Hospital for Sick Children", "source_org_type": "医院", "row_number": 1046, "target_meta": "IDH1", "MOA_meta": "抑制剂"}, {"drug_name": "[89Zr]Zr-DFO-Fab8", "company": "University of Alabama at Birmingham", "org_type": "大学", "target": "huCD68", "modality": "荧光显像剂", "importance_level": "低", "total_score": 49, "institution_score": 35, "track_score": 65, "milestone_score": 55, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "该药物为靶向人源CD68的Fab片段偶联89Zr的免疫PET显像剂，用于非侵入性检测肿瘤微环境中的泛巨噬细胞负担。机构为大学非商业研发导致institution_score较低，modality为早期免疫PET显像剂虽有临床转化潜力但非热门治疗赛道、仍处preclinical阶段，总分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10561", "id": "o57M_5wBZznHJdnt_W3O", "source_drug_name": "[89Zr]Zr-DFO-Fab8", "title": "ImmunoPET imaging of human tumor associated macrophages", "abstract_text": "Introduction: Macrophages are valuable imaging targets for inflammatory diseases, as they may reflect prognosis and response to therapy. Current noninvasive imaging agents that target different markers of macrophages are either nonspecific or preferentially identify the immunosuppressive macrophage subset. Here, we report the development of the first positron emission tomography (PET) tracer that targets human CD68 (huCD68), the clinically established pan-macrophage marker and its evaluation in the tumor microenvironment (TME).\nMethods: Fab8, previously identified through phage display, was conjugated with p-SCN-Bn-DFO chelator and radiolabeled with 89Zr to obtain [89Zr]Zr-DFO-Fab8. Binding specificity of the tracer was evaluated in vitro using THP-1 macrophages, and THP-1 undifferentiated cells was used as a control. NSG mice (n = 3) were inoculated with MDA-MB-231 cells, a triple negative breast cancer cell line that does not express huCD68, subcutaneously to both shoulders. After tumor growth, the mice were then intratumorally injected with THP-1 macrophages on the right tumor to establish a new model of human macrophages in the TME. As a control, undifferentiated THP-1 cells were injected into the left tumors at 1 h before tracer injection. These mice were then injected with 100 µL of 930 kBq (6.3 µg mass dose) of [89Zr]Zr-DFO-Fab8 and PET imaging was performed at 1 and 6 h post-injection (p.i.). The specific uptake of [89Zr]Zr-DFO-Fab8 was determined by calculating tumor-to-heart Standardized Uptake Value Ratios (SUVR). The presence of CD68 in the tumors were biologically validated by immunofluorescence (IF) staining.\nResults: [89Zr]Zr-DFO-Fab8 was produced with radiochemical yield >95%. [89Zr]Zr-DFO-Fab8 had significantly higher binding in THP-1 macrophages (10 ± 1.5 %) than in THP-1 undifferentiated cells (3.4 ± 0.11 % ; p = 0.016). The SUVR of [89Zr]Zr-DFO-Fab8 in THP-1 macrophages was determined to be 0.34 ± 0.05 and 0.48 ± 0.07 and in undifferentiated THP-1 was 0.18 ± 0.03 and 0.29 ± 0.03, at 1 and 6 h p.i. respectively. Tracer uptake in the THP-1 macrophage tumors was significantly higher than that in the undifferentiated THP-1 tumors at 1 and 6 h p.i. (p = 0.0120 and p = 0.0041, respectively). IF results showed more huCD68 staining in the THP-1 macrophage tumors vs the THP-1 undifferentiated tumors, further validating our immunoPET results.\nConclusion: We have developed the first immunoPET tracer targeting human CD68. [89Zr]Zr-DFO-Fab8 binds specifically to huCD68 in both an in vitro and in vivo model, making it a promising tracer for noninvasive imaging of macrophage burden in various diseases for future clinical studies.", "source_company": "University of Alabama at Birmingham", "source_org_type": "大学", "row_number": 1062, "target_meta": "CD68", "MOA_meta": "荧光显像剂"}, {"drug_name": "CD40 agonism", "company": "The University of Texas MD Anderson Cancer Center", "org_type": "医院", "target": "CD40", "modality": "other", "importance_level": "低", "total_score": 49, "institution_score": 40, "track_score": 75, "milestone_score": 40, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "CD40激动剂通过激活CD40通路增强免疫应答，常用于胰腺癌免疫治疗组合，但摘要被embargo未披露具体药物和细节。机构为顶级癌症中心但属医院/学术型而非药企，处于phase I试验在进展中但无具体数据，赛道有热度但整体信息不足导致分数偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/12188", "id": "qZ3ECZ0B4z9FlvORyiZD", "source_drug_name": "CD40 agonism", "title": "Trial in progress: A phase I study of personalized neoantigen vaccination combined with PD-1 blockade and CD40 agonism in resected pancreatic ductal adenocarcinoma", "abstract_text": "Abstract is embargoed at this time.", "source_company": "The University of Texas MD Anderson Cancer Center", "source_org_type": "医院", "row_number": 1079, "target_meta": "CD40", "MOA_meta": "其他"}, {"drug_name": "alpha-eleostearic acid", "company": "University of Chicago", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 49, "institution_score": 35, "track_score": 65, "milestone_score": 45, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "alpha-eleostearic acid（一种多不饱和脂肪酸）通过过载诱导铁死亡靶向药物耐受持久细胞，机制新颖但靶点未明确披露。大学机构+preclinical阶段+饮食干预策略导致整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9179", "id": "_J7M_5wBZznHJdnt_W3O", "source_drug_name": "alpha-eleostearic acid", "title": "Harnessing lipid metabolism to treat drug-tolerant persister cells", "abstract_text": "Pancreatic ductal adenocarcinoma (PDAC) remains one of the most lethal cancers, with a five-year survival rate of only 13% and limited response to current therapies. A major contributor to treatment failure is the emergence of drug-tolerant persister cells (DTPs), a slow-cycling subpopulation that survives targeted and systemic therapy and drives relapse. Here, we aimed to determine whether the metabolic dependencies of DTPs could be exploited to eliminate these cells. Through analysis of publicly available transcriptomic datasets across multiple malignancies, including PDAC, colorectal, breast, and non-small cell lung cancers, we identified consistent downregulation of SREBF1, a master regulator of de novo lipid synthesis, in DTPs. We previously demonstrated that PDAC cells with impaired lipogenesis are selectively vulnerable to exogenous polyunsaturated fatty acids (PUFAs) due to their inability to balance saturated and monounsaturated fatty acid pools, resulting in ferroptotic death. Based on these findings, we hypothesized that DTPs can be targeted through PUFA overload. To test this, we induced DTPs in murine PDAC cell lines using the KRAS-targeted therapy RMC-7977 and treated them with PUFAs, including alpha-eleostearic acid (ESA). ESA supplementation was sufficient to eradicate PDAC DTPs at dietarily achievable concentrations. We are now evaluating whether this approach can limit relapse by targeting minimal residual disease in animal models of PDAC treated with KRAS inhibitors. These findings reveal a diet-based strategy that exploits metabolic vulnerabilities of therapy-persistent PDAC cells and may reduce the risk of disease recurrence.", "source_company": "University of Chicago", "source_org_type": "大学", "row_number": 1127, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "nab-paclitaxel-bevacizumab", "company": "Mayo Clinic College of Medicine and Science", "org_type": "大学", "target": "VEGF", "modality": "nano-immunoconjugate", "importance_level": "低", "total_score": 49, "institution_score": 35, "track_score": 75, "milestone_score": 45, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "该nano-immunoconjugate利用bevacizumab靶向VEGF实现nab-paclitaxel的递送，属于抗体-纳米颗粒偶联形式。Mayo Clinic为大学机构非商业公司导致机构分较低，PopPK研究属早期阶段无显著临床里程碑，总分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5539", "id": "AZ7M_5wBZznHJdnt_W7O", "source_drug_name": "nab-paclitaxel-bevacizumab", "title": "Population pharmacokinetics of nab-paclitaxel following administration of a nano-immunoconjugate with bevacizumab", "abstract_text": "Introduction. This study aimed to characterize the population pharmacokinetics (PopPK) of nab-paclitaxel following the administration of the nano-immunoconjugate nab-paclitaxel-bevacizumab to patients with unresectable stage IV melanoma or gynecological cancers (NCT02020707). The core objective was to characterize the population mean drug concentration-time profile, understand the variability in drug concentrations and identify factors that explain differences in paclitaxel plasma clearance. Also, we sought to explore the impact of the nano-immunoconjugate formulation on paclitaxel clearance.\nMethods. Using Pumas AI - an advanced pharmacokinetic software program, integrating Machine Learning methods - a PopPK analysis was conducted using concentration-time data collected from 29 subjects, (681 concentration measurements). Patients received 75 - 175 mg/m2 (total dose, 160 - 360 mg). Data were fitted to a 2-compartment model based biphasic decline observed in plasma concentration following intravenous administration. A critical requirement for the model was the inclusion of saturable elimination to accurately describe the drug’s disposition. A comprehensive modeling workflow was implemented, starting with base models (mixed vs. non-linear clearance), followed by the sequential addition of covariates (Age, Sex, BSA, Tumor, Cycle). The Parsimony Principle was applied to select the most appropriate model.\nResults. Population estimates for paclitaxel clearance and volume of distribution were 41.7 L/hr and 312 L, respectively. The analysis found paclitaxel clearance higher when compared with published data for nab-paclitaxel alone (21.1 or 25 L/h/m2; Sparreboom et al, CCR 11:4136, 2005 and Ando et al, CCP 69:457, 2012). A covariate model incorporating BSA and Gender is the best. For every 2 m2 increase in BSA, linear clearance (CL) increases by 6.9%. Females have 16.6% lower CL than males, which successfully characterized systematic differences in PK between subgroups of subjects.\nConclusion. The administration of nab-paclitaxel via the nano-immunoconjugate formulation led to increased clearance for paclitaxel consistent with known clearance mechanisms for therapeutic antibodies. The differences in drug clearance among patients were primarily attributable to covariates BSA and gender. These findings are crucial for identifying safe and effective dosing regimens and informing future clinical simulations.", "source_company": "Mayo Clinic College of Medicine and Science", "source_org_type": "大学", "row_number": 1131, "target_meta": "VEGF family", "MOA_meta": "其他"}, {"drug_name": "anti-PD-1", "company": "Emory Winship Cancer Institute", "org_type": "医院研究机构", "target": "PD-1", "modality": "inhibitor", "importance_level": "低", "total_score": 49, "institution_score": 35, "track_score": 70, "milestone_score": 50, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "药品为通用anti-PD-1抑制剂，靶点PD-1；研究机构为医院/学术型，非头部药企导致institution_score较低，摘要聚焦VPAC阻断增强anti-PD-1疗效的机制研究，属preclinical层面无明确新药里程碑，总分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8151", "id": "tJ3ECZ0B4z9FlvORyiZD", "source_drug_name": "anti-PD-1", "title": "Androgen-driven sexual dimorphism reshapes immune crosstalk and limits immunotherapy response in PDAC", "abstract_text": "Pancreatic ductal adenocarcinoma (PDAC) remains a lethal cancer, with only 13% of patients surviving 5 years. The limited efficacy of anti-PD-1/PD-L1 therapies indicates that additional immunoregulatory pathways sustain the immunosuppressive tumor microenvironment (TME) that restricts T-cell infiltration. Our recent studies (Ravindranathan Nat Com 2022) demonstrated that combined blockade of vasoactive intestinal peptide (VIP) receptor (VPAC) and PD-1 signaling eradicated PDAC in ~50% of mice, although the underlying mechanism of VPAC inhibition remains undefined. Therefore, we hypothesized that VPAC blockade reshapes the immune microenvironment to enhance antigen presentation and T cell responses to anti-PD1 immunotherapy in PDAC.To address this, we characterized the expression of VIP and VPAC on cancer cells, immune cells, and stromal cells in the PDAC TME. We studied the impact of VPAC signaling on the immune functions of myeloid/lymphoid cells and on the architecture of the TME using PDAC patient specimens, murine models, and relevant in vitro/ex vivo systems. Tumor growth kinetics were performed to assess the anti-tumor potential of VPAC blockade.In vitro secretome analysis showed that murine MT5 PDAC cells secrete more VIP than KPC-luc, consistent with their faster tumor-growth kinetics. To assess host-intrinsic VIP effects in TME we compared tumor progression in WT and vip-knockout (vip-ko) mice and found markedly slower growth in vip-ko mice, especially in females vs. males. To explore the cellular basis of the anti-tumor response, we depleted immune cell subsets and compared tumor growth kinetics in both female and male vip-ko mice. Depletion of CD8+ or CD4+ T cells and of CSF1R+ myeloid cells accelerated tumor growth in vip-ko mice, whereas clodronate depletion of phagocytic macrophages attenuated anti-tumor responses only in females. Androgen blockade (ARB) with degarelix restored male responsiveness to VPAC inhibition, highlighting androgen-driven resistance in male against VPAC blockade. Mechanistically, VIP from CD29⁺PD-L1⁺ fibroblasts suppressed macrophage phagocytosis of PDAC cells, while VIP loss restored this activity. Strikingly, AR activation further suppressed macrophage phagocytosis selectively in males. Mechanistically, TNF-α and MIF secreted from γδ-T cells and GZMK⁺CD8⁺ T cells, respectively, enhanced anti-tumor phagocytosis in female vip-ko mice. Combined AR blockade, anti-PD-1, VPAC antagonism, and taxotere markedly extended survival in WT male mice bearing orthotopic MT5 PDAC (MST 54 vs. 18 days for untreated control).These findings show that VPAC signaling restrains TNF-α– and MIF-dependent immune crosstalk and limits phagocytic PDAC clearance. These data also reveal androgen-suppressed phagocytosis as a driver of sexual dimorphism in response to VPAC antagonism and suggest translatable approaches for PDAC treatment.", "source_company": "Emory Winship Cancer Institute", "source_org_type": "医院\n研究机构", "row_number": 1161, "target_meta": "PD1", "MOA_meta": "抑制剂"}, {"drug_name": "6F10", "company": "Dana-Farber Cancer Institute", "org_type": "医院", "target": "B7-H7", "modality": "inhibitor", "importance_level": "低", "total_score": 49, "institution_score": 40, "track_score": 75, "milestone_score": 30, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "6F10为B7-H7（HHLA2）阻断抗体（双阻断TMIGD2和KIR3DL3），可影响NK细胞激活，但Dana-Farber为学术医院机构而非商业药企，研究仍处于体外机制探索阶段，无临床开发迹象。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9468", "id": "NZ7M_5wBZznHJdnt_W7O", "source_drug_name": "6F10", "title": "Investigating the transcriptomic signature of B7-H7-mediated activation of NK cell activity", "abstract_text": "Determining how antibodies that target immune checkpoints alter lymphocyte functions can improve our understanding of immune checkpoint inhibitors responses in patients. HERV-H LTR-associating 2 (HHLA2, B7-H7) is an immune checkpoint expressed by many tumors. Our group previously found that B7-H7 has an inhibitory receptor, KIR3DL3, in addition to having an activating receptor, TMIGD2. Both B7-H7 receptors are expressed by subsets of T cells and NK cells. However, little is known about how different subsets of lymphocytes are affected by B7-H7 engagement of these receptors, and multiple B7-H7:KIR3DL3 blocking antibodies are currently enrolling cancer patients in Phase I clinical trials (NCT05824663, NCT06240728).In this study, we explored the effect of tumors expressing B7-H7 on NK cells in vitro by single cell RNA sequencing (scRNAseq). NK cells were isolated from peripheral blood and co-cultured with K562 cells or K562 cells overexpressing B7-H7 for 2hr. Co-cultures were performed in the presence of different B7-H7 blocking antibodies or isotype controls. 133,017 cells passed quality control, with 9 distinct NK cell populations being identified. Primary NK cells not co-cultured with tumor cells were mainly composed of two TXNIP+ CD96 hi NK cell clusters that had low expression of cytotoxic and inflammatory genes. Additionally, these two clusters had the highest expression of TMIGD2, suggesting that these populations represent resting NK cells. Co-culture with K562 or K562-B7-H7 cells increased the proportion of highly cytotoxic and inflammatory NK cell clusters. However, XCL2, CSF2, IFNγ and IL3 were higher in NK cells co-cultured with K562-B7-H7 than with K562, suggesting B7-H7 on K562 cells is proinflammatory in this early activation model. Notably, only a small subset of peripheral blood NK cells expressed the inhibitory receptor KIR3DL3, as expected in early NK activation. Furthermore, all antibody treatments regardless of the Fc isotype were associated with increased proportions of CRTAM+ IL2RA+ TNFRSF9+ NK cell clusters, compared to NK cells cultured without antibody. Differential gene expression analysis between B7-H7 antibody clones 6F10 and 2C4 by respective Fc (IgG1 or IgG4) suggested blocking TMIGD2 with the dual receptor blocking B7-H7 antibody (6F10) reduces the extent of activation of the NK cells compared to the B7-H7 antibody (2C4) that blocks KIR3DL3 but not TMIGD2.Our work suggests the importance of selecting B7-H7 therapeutics that spare the interaction of B7-H7:TMIDG2 to maintain any NK-dependent antitumor benefit of B7-H7 expression.", "source_company": "Dana-Farber Cancer Institute", "source_org_type": "医院", "row_number": 1162, "target_meta": "HHLA2", "MOA_meta": "抑制剂"}, {"drug_name": "lab-fabricated microbubbles", "company": "Duke University", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 49, "institution_score": 35, "track_score": 65, "milestone_score": 45, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "lab-fabricated microbubbles为实验室自制超声微泡，用于聚焦超声辅助开启血脑屏障，无明确药物靶点，仅作为递送工具。大学机构非商业主体、开发处于体外优化表征阶段导致综合重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/7237", "id": "Rp7M_5wBZznHJdnt_W7P", "source_drug_name": "lab-fabricated microbubbles", "title": "Fabrication and characterization of echogenic microbubbles for in vitro modeling of blood-brain barrier (BBB) disruption via focused ultrasound", "abstract_text": "The blood-brain barrier (BBB) presents a major obstacle to the delivery of many promising pharmacological agents to the central nervous system. The BBB is composed of tightly connected endothelial cells that regulate molecular exchange to maintain brain homeostasis. While this is beneficial for protecting the brain, over 98% of small-molecule and almost 100% of large-molecule drugs are blocked by the BBB, limiting treatment options for neurological diseases. Recently, bubble-assisted focused ultrasound (BaFUS) has emerged as a non-invasive strategy to transiently disrupt the BBB and facilitate targeted drug delivery by injected gas bubbles in the bloodstream. We previously developed a custom ultrasound-transparent organ-on-chip (UST-OoC) platform for modeling BaFUS-mediated BBB disruption in vitro. In this study, we report on the optimization and characterization of a microbubble formulation for use in BaFUS. Microbubbles were synthesized using a phospholipid-based protocol and characterized by dynamic light scattering (DLS) and zeta potential measurements. The formulation produced ~1 µm microbubbles with a neutral zeta potential and a concentration of 2.4 × 1010 bubbles/mL. Acoustic testing showed strong, sustained bubble cavitation across flow rates of 150-300 µL/min. An acoustic dose-response sweep revealed non-linear stable cavitation and inertial cavitation thresholds to be 0.08 and 0.32 MPa. These lab-fabricated microbubbles have the advantages of low cost and easy adjustment of size and concentration. The UST-OoC platform enables human-based in vitro modeling for real-time visualization of barrier disruption, quantitative permeability assessment, and systematic optimization of acoustic parameters, including pressure, frequency, and duty cycle under controlled flow conditions. This integrated system provides a scalable, reproducible preclinical tool for evaluating microbubble performance and BaFUS protocols prior to in vivo translation. By establishing human-based BBB models, standardized methods for microbubble fabrication, acoustic characterization, and barrier disruption modeling, this platform addresses key translational gaps in developing BaFUS-enhanced drug delivery for brain disorders.", "source_company": "Duke University", "source_org_type": "大学", "row_number": 1174, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "ATP-gated protein system", "company": "Harvard College", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 49, "institution_score": 35, "track_score": 75, "milestone_score": 35, "field_heat_score": 65, "bonus_score": 3, "brief_reason": "利用肿瘤微环境高浓度eATP设计ATP-gated蛋白实现肿瘤选择性药物递送，靶点和具体药物形式未明确披露。大学早期概念验证工作（仅NMR初步结合验证，Kd≈250µM），赛道新颖但整体开发阶段极早期且非产业化主体导致综合重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3548", "id": "jJ7M_5wBZznHJdnt_W7P", "source_drug_name": "ATP-gated protein system", "title": "Designing ATP-gated proteins for tumor selective drug delivery", "abstract_text": "Chemotherapy remains limited by lack of specificity in many existing treatments, motivating the need for therapeutic strategies that exploit molecular features unique to the tumor microenvironment (TME). A defining hallmark of the TME is the elevated concentration of extracellular ATP (eATP), which can rise ~1000-fold from nanomolar levels in healthy cells to ~100 µM in tumors. eATP promotes tumor growth and immune evasion, making it an attractive biochemical feature for tumor targeting. In this work, we used state of the art deep learning-based protein design methods to generate scaffolds capable of selectively binding ATP and experimentally validated their binding as an initial step toward developing ATP-gated systems for tumor-specific drug delivery. To accomplish this, we adapted our lab’s Neural Iterative Selection and Expansion (NISE) workflow, which integrates deep learning-based sequence design and structure prediction. In this framework, ATP was first docked into candidate protein scaffolds to define the binding-site geometry. A sequence design model then generated amino acid sequences predicted to fold into stable structures accommodating the positioned ligand, after which a structure prediction network modeled the complex to assess self-consistency between the designed sequence and structure. The designed sequences were then filtered based on high structural similarity (indicating designability) and high confidence (reflecting complex plausibility), and top-performing designs were used as input for the next round of sequence generation. Across twenty NISE refinement cycles, the algorithm progressively enriched for protein-ATP complexes by optimizing the joint space of sequence, structure, and ligand conformation. The workflow ultimately produced ~2,600 candidate complexes, from which a small set of high-quality designs were selected for experimental validation. The designs were tested using NMR spectroscopy. One top construct displayed ¹H-chemical-shift perturbations upon ATP titration (Kd ≈ 250 µM), consistent with the predicted isoleucine-adenine stacking interaction. Subsequent design rounds aimed to increase affinity by introducing features observed in natural ATP-binding proteins such as π-π stacking and expanded hydrogen-bonding motifs. In addition, the candidate protein structures were modified from 4-helix to 7-helix bundles to expand and solvate the binding pocket, enhancing hydrogen bonding, electrostatic complementarity, and water-mediated interactions. Together, these efforts represent the first step toward developing ATP-gated protein systems that can serve as tumor-selective drug delivery platforms, reducing the side effects commonly associated with chemotherapy in future applications.", "source_company": "Harvard College", "source_org_type": "大学", "row_number": 1219, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "LN019", "company": "Shanghai Jiao Tong University", "org_type": "大学", "target": "HER2", "modality": "ADC", "importance_level": "低", "total_score": 49, "institution_score": 30, "track_score": 85, "milestone_score": 40, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "LN019为新型HER2靶向affibody-drug conjugate（ADC类），在异种移植瘤模型中显示优于T-DXd的抗肿瘤效果。大学机构分数较低，赛道（HER2+ADC）热度较高但仅为preclinical xenograft数据，整体重要性有限。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11302", "id": "ZVXM_5wBX1NQZOEH-LO6", "source_drug_name": "LN019", "title": "LN019, a novel HER2-targeting affibody-drug conjugate, demonstrates superior antitumor efficacy compared to T-DXd in xenograft models", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Shanghai Jiao Tong University", "source_org_type": "大学", "row_number": 1250, "target_meta": "HER2", "MOA_meta": "抗体偶联药物"}, {"drug_name": "miR-1293", "company": "Center for Cancer Research", "org_type": "研究机构", "target": "S100A16-Hippo-EMT axis", "modality": "other", "importance_level": "低", "total_score": 48.5, "institution_score": 30, "track_score": 65, "milestone_score": 55, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "miR-1293作为肿瘤抑制性miRNA，通过靶向S100A16-Hippo-EMT轴在弥漫性胸膜间皮瘤中显示抗肿瘤作用，机制新颖且针对Hippo通路失调亚型有选择性活性。机构为政府研究机构非商业公司、仍处preclinical阶段、在体外和体内模型有效但无产业化推进，导致总体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/2351", "id": "0lXM_5wBX1NQZOEH-LK6", "source_drug_name": "miR-1293", "title": "miR-1293 suppresses diffuse pleural mesothelioma growth by targeting a novel S100A16-Hippo-EMT axis", "abstract_text": "Background: Diffuse pleural mesothelioma (DPM) features frequent NF2 loss, Hippo pathway disruption, and limited therapies. We identify miR-1293 as a tumor-suppressive miRNA that targets an S100A16-centered Hippo/EMT axis involving Hippo/YAP and epithelial-mesenchymal transition (EMT) in DPM. Methods: We performed a high-throughput human miRNA mimic screen across multiple DPM cell lines with proliferation assays to identify anti-tumor miRNAs. miR-1293 expression was measured by qRT-PCR in DPM tumors and normal pleura. Targets were mapped by biotin-miR-1293 pulldown plus RNA-seq and in silico prediction, then integrated with pathway and DepMap data to define an S100A16-Hippo/EMT module. Functional effects of miR-1293 re-expression were tested in NF2-wild-type and NF2/Hippo-deficient DPM lines and in MB52 xenografts using local hydrogel-based (SFH-miR-1293) delivery in subcutaneous and orthotopic pleural models. Results: The screen identified miR-1293 as a top antiproliferative miRNA, and miR-1293 was significantly underexpressed in DPM versus normal pleura. Re-expression in miR-1293-low DPM lines reduced proliferation, colony and soft-agar growth, with minimal impact on non-malignant mesothelial cells, and induced apoptosis and cell-cycle arrest. Target mapping yielded 345 genes enriched for Hippo signaling and EMT, with additional mTORC1, IL-2/STAT5, and hypoxia signatures, and a 19-gene core S100A16-Hippo-EMT module. Within this module, S100A16 was the most essential and strongest adverse prognostic gene, highly expressed in NF2/Hippo-deficient lines (H2052, MB52, MB24) with activated YAP/TAZ/TEAD and EMT-like features. miR-1293 re-expression preferentially impaired viability and clonogenicity in these NF2/Hippo-deficient cells, with coordinated suppression of S100A16, YAP/TAZ/TEAD, and EMT markers. In vivo, SFH-miR-1293 significantly reduced tumor burden, Ki-67, and bioluminescence, increased cleaved caspase-3, and prolonged survival in xenograft and orthotopic pleural models. Conclusions: miR-1293 is a tumor-suppressive miRNA in DPM that targets an S100A16-Hippo-EMT axis and shows preferential activity in NF2/Hippo-deficient mesothelioma. Local hydrogel-based delivery elicits strong antitumor effects in vivo, supporting miR-1293 as a therapeutic candidate for DPM and a rational partner for Hippo/YAP-directed and immunotherapy strategies.", "source_company": "Center for Cancer Research", "source_org_type": "研究机构", "row_number": 623, "target_meta": "S100A16", "MOA_meta": "其他"}, {"drug_name": "hSSB2 activator", "company": "BCN Biosciences", "org_type": "公司", "target": "hSSB2", "modality": "other", "importance_level": "低", "total_score": 48.5, "institution_score": 45, "track_score": 70, "milestone_score": 30, "field_heat_score": 50, "bonus_score": 3, "brief_reason": "hSSB2 activator作为首创药物针对RAS/MAPK抑制剂耐药的双重策略，机制新颖但靶点非热门。BCN Biosciences为小型preclinical阶段biotech，开发早期且摘要被禁导致信息有限，整体热度和里程碑价值较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11459", "id": "jFXM_5wBX1NQZOEH-LO6", "source_drug_name": "hSSB2 activator", "title": "First in class hSSB2 activator as a dual therapeutic strategy for overcoming RAS/MAPK inhibitor resistance while protecting normal epithelia in aggressive cancers", "abstract_text": "Abstract is embargoed at this time.", "source_company": "BCN Biosciences", "source_org_type": "公司", "row_number": 743, "target_meta": "NABP1", "MOA_meta": "其他"}, {"drug_name": "RMC-9945", "company": "Sheba Medical Center", "org_type": "医院", "target": "未披露", "modality": "inhibitor", "importance_level": "中", "total_score": 48.5, "institution_score": 25, "track_score": 85, "milestone_score": 45, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "RMC-9945为RAS(ON) G12D选择性抑制剂，靶向KRAS G12D突变驱动的PDAC，与PARPi联用在患者来源模型中显示协同抗肿瘤效应。机构为医院而非药企导致institution_score偏低，但RAS(ON)抑制剂赛道热度高、胰腺癌未满足需求强，总分处于中位。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4013", "id": "a57M_5wBZznHJdnt_W7P", "source_drug_name": "RMC-9945", "title": "Dual targeting of PARP and RAS enhances antitumor activity in pancreatic cancer", "abstract_text": "KRAS is the most frequent oncogenic mutation in PDAC. KRAS drives tumorigenesis and enhances mechanisms of DNA-damage repair (DDR). Specifically, KRAS upregulates HR and non-homologous end joining (NHEJ), which are critical pathways for DNA repair. Dual inhibition of these two driver pathways in BRCAmut PDAC, the MAPK/KRAS and the DDR, may have a promising therapeutic effect. However, this effect may be also exploited in the general PDAC population. PARP and RAS combined inhibition may extend and deepen therapeutic effect and delay emergence of therapeutic resistance.Our main goal was to examine the therapeutic effect of PARP and RAS(ON) combined inhibition on tumor growth in BRCAmut and BRCA-WT preclinical models. We established pre-clinical patient derived xenografts (PDX) models (n=160), PDX derived cells (n=37) and 3D organoids (n=11). Models were analyzed by WGS and RNAseq. We tested the effect of PARPi (olaparib) in combination with two RAS inhibitors: A tool RAS(ON) -multi-selective inhibitor RMC-7977 and a tool RAS(ON) G12D-selective inhibitor RMC-9945 (RM-044) in-vitro and in-vivo, utilizing specific models’ systems based on BRCA and KRAS status (n=12).In vitro, PDCs were treated with olaparib, RMC-7977, RMC-9945 and combinations for 5 days. A dose response curve was observed for each cell line, with a variability of response between cell lines. Combination of RAS(ON)i and olaparib exhibited significant additive effect. In 3D organoids, combinational treatment of olaparib and RMC-7977 demonstrated a profound effect on viability. This effect was noted on BRCAmut and BRCA-WT cell lines. In-vivo experiment in a platinum sensitive BRCA2 mutated PDX model both RMC-7977 and RMC-9945 significantly attenuated tumor growth rate compared to control (p<0.05). The combination demonstrated a comparable effect to PARPi monotherapy. Yet, a tendency towards an enhanced response was observed by ex-vivo tumor volume and tumor weight. We hypothesize that a longer duration of experiment (currently being performed) will enhance response and delay the emergence of therapeutic resistance. In parallel mechanistic functional assays are being performed. Overall, we demonstrate a superior effect of the combination of PARPi and RAS(ON)i on PDAC using patient-derived models in-vitro (BRCAmut and BRCA WT) and in-vivo (BRCAmut). Notably, most models were generated from tumors obtained from patients at clinical resistance to standard of care treatment reflecting models with aggressive biology. Thus, these findings support further evaluation of combinational treatment of both RAS(ON) and PARP inhibition in this population.", "source_company": "Sheba Medical Center", "source_org_type": "医院", "row_number": 1195, "target_meta": "not available", "MOA_meta": "抑制剂"}, {"drug_name": "a novel high-affinity monoclonal antibody against CD160", "company": "Mohammed VI Polytechnic University", "org_type": "university", "target": "CD160", "modality": "monoclonal antibody", "importance_level": "低", "total_score": 48, "institution_score": 35, "track_score": 65, "milestone_score": 45, "field_heat_score": 55, "bonus_score": 2, "brief_reason": "靶向CD160的双重机制单抗（免疫检查点+抗血管生成），但研发机构为大学，处于早期研究阶段（in vitro/ex vivo），缺乏临床进展。综合机构非头部、开发阶段初步，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1536", "id": "dFXM_5wBX1NQZOEH-LO6", "source_drug_name": "a novel high-affinity monoclonal antibody against CD160", "title": "Targeting CD160 as an immunotherapy approach to modulate tumor angiogenesis and improve outcomes in triple-negative breast cancer", "abstract_text": "Triple-negative breast cancer (TNBC) is an aggressive subtype with limited treatment options and poor clinical outcomes. While immune checkpoint inhibitors (ICIs) have shown promise in TNBC, many patients remain unresponsive, highlighting the urgent need for new immunotherapeutic targets and mechanisms. CD160, a GPI-anchored receptor expressed on cytotoxic immune and endothelial cells, we have recently been proposed CD160 as a novel immune checkpoint inhibitor in solid tumors (Scheffges, Devy, et al. 2024). In this study, we investigated CD160 as a dual therapeutic target in TNBC, combining immunoregulatory and anti-angiogenic potential. Using a novel high-affinity monoclonal antibody against CD160, we demonstrate that targeting this receptor significantly inhibits pathological angiogenesis and promotes vascular normalization in vitro and ex vivo, without inducing cytotoxicity. These effects may contribute to enhanced immune infiltration and improved tumor perfusion, ultimately improving patient survival. To better understand CD160’s mechanism of action, we explored its molecular interactions in human endothelial cells. Super-resolution microscopy and functional assays revealed that CD160 physically associates with LRP1, identifying it as a potential co-receptor involved in its vascular effects. These findings support the development of CD160-targeted immunotherapy as a promising strategy for TNBC, acting both as an immune checkpoint inhibitor and a modulator of the tumor vasculature.\nReferences : Scheffges C, Devy J, Giustiniani J, Francois S, Cartier L, Merrouche Y, Foussat A, Potteaux S, Bensussan A, Marie-Cardine A. Identification of CD160-TM as a tumor target on triple negative breast cancers: possible therapeutic applications. Breast Cancer Res. 2024 Feb 15;26(1):28. doi: 10.1186/s13058-024-01785-x. PMID: 38360636; PMCID: PMC10870674.", "source_company": "Mohammed VI Polytechnic University", "source_org_type": "大学", "row_number": 728, "target_meta": "CD160", "MOA_meta": "单抗"}, {"drug_name": "ACP", "company": "University of Iowa", "org_type": "大学", "target": "CGRPR", "modality": "RLT imaging agent", "importance_level": "低", "total_score": 48, "institution_score": 30, "track_score": 70, "milestone_score": 60, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "ACP为靶向CGRPR的theranostic放射性配体（SPECT成像+177Lu靶向放疗），机制新颖针对癌症相关CGRP轴，但CGRPR在癌症中的靶向治疗仍属早期探索，未见临床进展。大学机构+preclinical阶段导致总体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3898", "id": "zlXM_5wBX1NQZOEH-LO6", "source_drug_name": "ACP", "title": "Theranostics targeting the calcitonin gene-related peptide receptor (CGRPR) demonstrate efficacy in a preclinical mouse model of human cancer", "abstract_text": "Introduction: Recent literature demonstrates that the CGRPR, and its primary ligand, calcitonin gene-related peptide (CGRP) are implicated in 9 of the 14 hallmarks of cancer and contribute to the development of multiple primary cancers. Here, we developed a theranostic strategy for the SPECT imaging and targeted radiotherapy of CGRPR-positive tumors.\nMethods: The CGRPR-specific bioconjugate DOTA-Bn-NCS-FV-Tic-TDVGPFAF (ACP) was radiolabelled with 111In (SPECT: t1/2 = 2.8 d; Ee-max = 0.245 MeV) or 177Lu (β - emitter: t1/2 = 6.7d; E β-max = 0.497 MeV). Biodistribution studies in CGRPR+ HTB-10 tumor-bearing mice were conducted using [111In]In-ACP and radioactivity in tissue was quantified against a known radioactivity standard. Therapy studies with [177Lu]Lu-ACP in the same tumor bearing model were also completed. As animals reached clinical endpoints, the animals were euthanized and processed for histology. QuPath software was used to quantify immunohistochemistry images, while survival and statistical analysis was accomplished using GraphPad Prism v.10.2.\nResults: The acute biodistribution of [111In]In-ACP revealed rapid excretion from blood, liver, kidney and bone suggesting effective clearance that may lead to acceptable dosimetry in dose-limiting organs such as the kidney and bone marrow. A tumor-to-muscle ratio of 39 at 4 h p.i., which was reduced to 12 with peptide blockade suggests that the radiopharmaceutical interacts with the CGRPR through a receptor mediated mechanism. Radiotherapy studies revealed that CGRPR+ HTB-10 tumor bearing mice injected with [177Lu]Lu-ACP experienced a survival benefit when compared to animals receiving control treatments (p = 0.036). When analysed histologically, tumor sections from animals receiving the radiotherapy exhibited decreased Ki-67 staining (proliferation marker) but higher caspase-3 (apoptosis marker) staining when compared to tumor sections of untreated animals.\nConclusion: Although the CGRPR/CGRP axis is implicated in cancer development, no theranostic strategies exist currently that target this receptor for imaging and therapy. Available data with [111In]In-ACP revealed effective tumor targeting and rapid clearance from normal tissues, while radiotherapy studies with [177Lu]Lu-ACP demonstrated effective tumor growth control. These results suggest targeting the CGRPR/CGRP axis warrants further exploration as a promising new strategy for the imaging and therapy of cancer.", "source_company": "University of Iowa", "source_org_type": "大学", "row_number": 796, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "selective haem oxygenase-1 inhibitor", "company": "King's College London", "org_type": "大学", "target": "HO-1", "modality": "inhibitor", "importance_level": "低", "total_score": 48, "institution_score": 35, "track_score": 55, "milestone_score": 60, "field_heat_score": 50, "bonus_score": 3, "brief_reason": "靶向HO-1的选择性抑制剂，旨在改善肿瘤微环境中TAM介导的免疫抑制并协同化疗产生抗肿瘤效应。大学早期研究，in vivo显示协同化疗疗效且有BBB穿透潜力，但机构权重低且赛道非当前最热门，导致总分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5744", "id": "X1XM_5wBX1NQZOEH-LS6", "source_drug_name": "selective haem oxygenase-1 inhibitor", "title": "Development of a selective haem oxygenase-1 inhibitor for the immunotherapy treatment of cancer", "abstract_text": "Immunotherapy has been hailed as a breakthrough for cancer therapy, however, only a fraction of patients respond in the clinic. The tumour microenvironment (TME) represents a major obstacle to the success of these treatments in solid tumours, of which, tumour-associated macrophages (TAMs) play a major role. A sub-population of perivascular TAMs express an enzyme called haem oxygenase-1 (HO-1), through which they have been demonstrated to subvert the anti-tumour response by immune suppression and exclusion of CD8+ T cells. HO-1+ TAM-containing tumours can therefore negate the immune-stimulating effects of chemotherapy to become treatment-resistant. Inhibiting HO-1 has been demonstrated to reverse this effect and re-sensitise tumours to immune-dependent cell death. However, there are no clinically available HO-1 inhibitors, and the current landscape of candidates suffer from undesirable pharmacokinetics and exhibit isoform promiscuity; blocking the activity of both HO-1 and the HO-2 isoform which maintains redox homeostasis in healthy tissues.This study has developed several novel, selective HO-1 inhibitors using a synthetic chemistry approach and validated activity with an in vitro microsomal system. We identified two lead compounds based on selectivity and potency for HO-1. A preliminary safety screen took place in vitro using non-malignant cells and confirmed a lack of general toxicity. Anti-tumour efficacy was evaluated in vivo using a murine model of fibrosarcoma, where administration of either lead HO-1 inhibitor synergised with standard-of-care chemotherapy to deliver durable tumour control and was associated with a re-invigorated lymphoid compartment. We utilised in silico modelling to predict lead compound pharmacokinetics, which are expected to be orally bioavailable. Unexpectedly, one of these candidates effectively penetrates the blood brain barrier, which is now under investigation for therapeutic utility in glioblastoma.", "source_company": "King's College London", "source_org_type": "大学", "row_number": 895, "target_meta": "HMOX1", "MOA_meta": "抑制剂"}, {"drug_name": "BI09", "company": "National Tsing Hua University", "org_type": "大学", "target": "IRE1-XBP1s", "modality": "inhibitor", "importance_level": "低", "total_score": 48, "institution_score": 35, "track_score": 65, "milestone_score": 45, "field_heat_score": 60, "bonus_score": 2, "brief_reason": "BI09为ER stress抑制剂，主要靶向IRE1-XBP1s通路，逆转DOX耐药并恢复NK细胞敏感性。由大学机构研发，preclinical阶段仅在耐药细胞系及小鼠模型中验证，整体开发价值和机构权重有限。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4935", "id": "jZ7M_5wBZznHJdnt_W7P", "source_drug_name": "BI09", "title": "Overcoming chemoresistance: Restoring doxorubicin sensitivity and natural killer cell immunity in resistant DLBCL cells through reduction of endoplasmic reticulum stress", "abstract_text": "The recurrence of diffuse large B-cell lymphoma (DLBCL) is commonly attributed to its resistance to doxorubicin (DOX), which presents a significant therapeutic challenge and contributes to poor prognosis. Endoplasmic reticulum (ER) stress, pivotal in DOX resistance, is governed by regulating the survival of tumor cells and immune evasion. This study developed DOX-resistant DLBCL cell lines using murine xenografts to investigate the underlying mechanisms and potential therapeutic strategies. Comprehensive analyses were performed, focusing on stress-response pathways, oncogene-driven immunomodulatory signaling, and the cytotoxic activity of natural killer (NK) cells. Resistant cells exhibited elevated IRE1-XBP1s activation and c-MYC expression, which compromised NK cell-mediated tumor killing and reinforced immune evasion. Inhibition of XBP1s through ER stress inhibitor BI09 effectively dismantled this compensatory resistance strategy, reinstated NK cell sensitivity, and substantially increased tumor cell apoptosis. Notably, the combination of BI09 with DOX resulted in substantial anti-lymphoma activity at reduced DOX concentrations, thereby overcoming chemoresistance. These findings indicated that BI09 operated through a dual approach, simultaneously restoring chemosensitivity in refractory DLBCL and counteracting c-MYC-mediated immune evasion. Consequently, this study underscored the IRE1-XBP1s-c-MYC axis as a pivotal pathway in chemoresistance and immune suppression in DLBCL cells, and identified BI09 as a viable therapeutic candidate capable of disrupting chemoresistance and enhancing the efficacy of immunochemotherapy in aggressive lymphoma.", "source_company": "National Tsing Hua University", "source_org_type": "大学", "row_number": 1220, "target_meta": "IRE1,XBP1", "MOA_meta": "抑制剂"}, {"drug_name": "ATR inhibitor", "company": "University of Kansas Medical Center", "org_type": "大学", "target": "ATR", "modality": "inhibitor", "importance_level": "低", "total_score": 47.8, "institution_score": 25, "track_score": 75, "milestone_score": 45, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "药物为ATR抑制剂，靶向DNA损伤应答关键激酶ATR，具有潜在增敏端粒氧化损伤的协同机制。机构为大学，处于早期机制研究阶段，缺乏明确临床开发进展，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/2032", "id": "OFXM_5wBX1NQZOEH-LS6", "source_drug_name": "ATR inhibitor", "title": "Oxidative base damage to telomeres sensitizes cancer cells to ATR inhibition", "abstract_text": "Targeted inhibition of DNA damage response proteins has received significant clinical attention owing to the success of PARP inhibitors. Due to the loss of G1/S checkpoint proteins like p16 and p53, cancer cells are reliant on the G2/M checkpoint to cope with elevated DNA replication stress, making them vulnerable to ATR and Chk1 inhibition. Cancer cells also experience elevated levels of oxidative stress, and targeting this is another therapeutic strategy, especially in photodynamic therapy. Our group has developed a chemoptogenetic tool (FAP-TRF1) which allows for targeted induction of singlet oxygen mediated 8-oxo-guianine (8oxoG) at telomeres. We previously demonstrated a single induction of 8oxoG at telomeres in cancer cells was sufficient to induce replication stress but was well tolerated at the cellular level. This led us to hypothesize that oxidative base damage to telomeres may sensitize cancer cells to low dose ATR inhibition. In this study we found inhibition of ATR, Chk1, or Wee1 after induction of telomeric 8oxoG significantly induced genome instability and reduced viability of cancer cells. This occurred at doses markedly less than those required to increase instability in non-cancer cells, and at levels in the cancer cells which the drug alone had no effect. We found p53 was critically protective of the non-cancerous cells in our model. We determined genome instability after 8oxoG induction and ATR inhibition was enhanced when cells were damaged in S-phase and when Mre11 was inhibited, while CDC7 inhibition restored stability. This phenotype resulted in an increased amount of time required to complete mitosis suggesting cells entered mitosis with unresolved replication intermediates. Indeed, pharmacologic prevention of mitotic entry during ATR inhibition rescued the genome instability caused by telomere oxidation. Together our findings indicate that manipulating the levels of reactive oxygen species in cancer cells may be an effective therapeutic alongside ATR inhibitors, allowing for tumor destruction while mitigating off-target effects to non-diseased tissue.", "source_company": "University of Kansas Medical Center", "source_org_type": "大学", "row_number": 872, "target_meta": "ATR", "MOA_meta": "抑制剂"}, {"drug_name": "anti-PD-L1 antibody", "company": "Chungnam National University", "org_type": "大学", "target": "PD-L1", "modality": "inhibitor", "importance_level": "低", "total_score": 47.8, "institution_score": 25, "track_score": 75, "milestone_score": 45, "field_heat_score": 65, "bonus_score": 3, "brief_reason": "anti-PD-L1抗体靶向PD-L1阻断免疫检查点，与IL-7分泌型沙门氏菌联合在CT26模型中实现4/5小鼠完全肿瘤消退并建立持久免疫记忆。大学机构基础研究阶段，创新组合有一定亮点但整体开发成熟度低、机构权重有限导致总分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10428", "id": "_57M_5wBZznHJdnt_W3O", "source_drug_name": "anti-PD-L1 antibody", "title": "IL-7-secreting Salmonella synergizes with PD-L1 blockade to induce durable antitumor immune memory", "abstract_text": "Background: Interleukin-7 (IL-7) is a key cytokine that maintains the survival and homeostasis of T cells and induces antitumor immune responses. This study investigated the antitumor effects of attenuated Salmonella genetically engineered to secrete IL-7 against cancer by activating immune cell responses.\nMethods: Mouse colorectal cancer cell line CT26 and S. typhimurium were used. The S. typhimurium was engineered to secrete IL-7 based on an arabinose induction system. The anti-tumor effect of the engineered Salmonella was examined in vitro and in vivo, both alone and in combination with anti-PD-L1 treatment. Flow cytometry was performed to analyze immune cell populations in tumors and spleens to elucidate the underlying mechanisms.\nResults: The genetically engineered Salmonella secreted IL-7 upon arabinose induction without affecting its growth. IL-7 secretion in response to arabinose was confirmed via ELISA. In in vivo experiments, the arabinose-induced group exhibited enhanced antitumor effects and improved survival compared to the non-induced group, with body weight recovery observed within five days post-Salmonella injection. TUNEL analysis showed increased apoptosis in tumor tissues following arabinose induction, along with a significant reduction in Ki67 expression. On days 3 and 7 post-induction, flow cytometry revealed an increased T cell population. The activation of cytotoxic T cells was confirmed by elevated levels of granzyme B, perforin, and IFN-γ. Co-administration of IL-7-secreting Salmonella with anti-PD-L1 antibody resulted in significantly greater tumor suppression compared to Salmonella secreting IL-7 alone. Notably, in the arabinose-induced group, complete tumor regression was observed in 4 out of 5 mice. When tumor cells were re-challenged on the opposite flank 60 days later, no tumor recurrence was detected, indicating the establishment of long-term antitumor immunity. Subsequent flow cytometric analysis of splenocytes confirmed an increased population of memory T cells, supporting the development of durable immune memory following IL-7 secretion. Biodistribution analysis showed that Salmonella was cleared from other organs over time, with predominant accumulation in tumor tissue. Biochemical analyses of liver and kidney function revealed no abnormalities in the arabinose-treated group. The biological\nsafety of the Salmonella strain was confirmed through biodistribution studies and H&E staining.\nConclusion: The Salmonella secreting IL-7 enhances antitumor activity by inducing T cell-mediated immune responses, particularly showing potential as an immunotherapy strategy for solid tumors when combined with anti-PD-L1 antibodies. Further research is needed to evaluate its efficacy in various tumor models, long-term safety, and the potential for combination with other immune checkpoint inhibitors.", "source_company": "Chungnam National University", "source_org_type": "大学", "row_number": 1129, "target_meta": "PDL1", "MOA_meta": "抑制剂"}, {"drug_name": "NEK2 inhibitor", "company": "University of North Carolina at Chapel Hill", "org_type": "大学", "target": "NEK2", "modality": "inhibitor", "importance_level": "低", "total_score": 47.5, "institution_score": 35, "track_score": 45, "milestone_score": 65, "field_heat_score": 55, "bonus_score": 2, "brief_reason": "靶向NEK2的抑制剂在EBV阳性非霍奇金淋巴瘤中显示机制作用并逆转耐药、降低肿瘤负荷。大学机构基础研究阶段、NEK2非热门靶点且modality常规导致整体赛道热度和机构评分较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4448", "id": "9VXM_5wBX1NQZOEH-LC5", "source_drug_name": "NEK2 inhibitor", "title": "NEK2 drives pathogenesis, drug resistance, and LMP1 expression in EBV-positive non-Hodgkin lymphoma", "abstract_text": "Non-Hodgkin lymphoma (NHL) is one of the most common cancers worldwide, representing 90% of malignant lymphomas. NHL is a diverse group of malignancies, and a subset of these lymphomas are caused by infection with the human gammaherpesvirus, Epstein-Barr virus (EBV). Many EBV-positive lymphomas are highly aggressive and rapidly develop resistance to treatment, leading to poor patient outcomes. Here, we identify the cellular kinase, NEK2, as a therapeutic target for EBV-positive NHL. We demonstrate NEK2 protein expression is increased in primary lymphocytes following EBV infection, NEK2 expression is significantly upregulated in EBV-positive NHL, and that NEK2 is necessary for the growth and survival of EBV-positive NHL. Inhibition of NEK2 resulted in lymphoma-specific cell death characterized by reactive oxygen species accumulation and gasdermin D cleavage. Additionally, protein levels of the major EBV oncoprotein, LMP1, were decreased following NEK2 inhibition. Furthermore, we demonstrate that MRP1 is the major drug resistance transporter protein in EBV-positive NHL. NEK2 inhibition reduced the expression and activity of cellular drug resistance transporter proteins including MRP1, leading to increased lymphoma cell chemosensitivity. Finally, using a humanized mouse model of EBV-driven lymphomagenesis, we demonstrate that NEK2 inhibition significantly decreased tumor burden and tumor incidence while prolonging survival in vivo. Taken together, our data suggest NEK2 inhibition as a promising treatment strategy for EBV-positive NHL.", "source_company": "University of North Carolina at Chapel Hill", "source_org_type": "大学", "row_number": 2, "target_meta": "NEK2", "MOA_meta": "抑制剂"}, {"drug_name": "bis-N-heterocyclic carbene-protected Au13 nanoclusters", "company": "University of Toronto", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 47.5, "institution_score": 35, "track_score": 65, "milestone_score": 45, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "该金纳米簇作为光动力治疗（PDT）增敏剂，具有高ROS产生效率和体外高效杀伤胰腺癌细胞的潜力，但靶点未明确披露。大学早期体外研究阶段，创新性NHC保护机制带来一定亮点，但整体开发阶段早、机构非产业化主体导致重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9309", "id": "LVXM_5wBX1NQZOEH-LG5", "source_drug_name": "bis-N-heterocyclic carbene-protected Au13 nanoclusters", "title": "Atomically precise NHC-stabilized gold nanoclusters for enhanced photodynamic and X ray activated cancer therapy", "abstract_text": "Gold nanoclusters (AuNCs) are atomically precise, ultrasmall (<2 nm) nanoparticles that exhibit favorable biocompatibility and renal clearance properties1-2. N-heterocyclic carbene (NHC) functionalized gold nanoclusters (NHC-AuNCs) are a new class of nanomaterials with high chemical stability, structural tunability, and strong potential to amplify radiation-induced cytotoxicity 3-4. We have synthesized bis-N-heterocyclic carbene (NHC)-protected Au13 nanoclusters that display intrinsic photoluminescence quantum yields, making them attractive candidates for cancer theranostics. Our objective is to improve their therapeutic performance by enhancing their distribution, increasing their tumor-targeting capability, and employing them as sensitizers for photodynamic therapy and/or radiotherapy (RT). In this work, we developed novel NHC-AuNCs with ~20-30% reactive oxygen species (ROS) production efficiency, a key property for inducing ROS-mediated DNA damage in cancer cells. We performed in vitro studies, including cytotoxicity, cellular uptake, and PDT potency evaluation, to assess their effectiveness as PDT agents. ICP-MS analyses verified efficient cellular uptake across multiple pancreatic cancer cell lines. Upon PDT irradiation at 10 and 20 J/cm2, treatment with 5 µM NHC-AuNCs induced over 90% cell death, whereas negligible cytotoxicity was observed in both non-AuNC-treated and no-light-treated control groups. These NHC-AuNCs show high PDT efficacy at half the concentration compared to previously tested AuNCs, making them a potent PDT agent. Ongoing work focuses on refining the nanocluster framework to enhance tumor specificity. The incorporation of surface azide groups enables click-chemistry conjugation of targeting peptides to improve tumour targeting. In parallel, in vivo studies assessing biodistribution, PDT efficacy, and survival outcomes in tumor-bearing models are underway to establish the therapeutic potential of these NHC-stabilized AuNCs.The ability of these nanoclusters to act as potent PDT agents provides a powerful nanoplatform for advancing cancer targeted therapy. The ability of various NHC-AuNCs with different photophysical and chemical properties to act as PDT agents will be discussed.\nReferences [1] Huang, Y etc., Nat. Nanotechnol. 2023, 18 (6), 637-646. [2] Zhang, X.-D. etc., Enhanced Tumor Accumulation of Sub-2 Nm Gold Nanoclusters for Cancer Radiation Therapy. Advanced Healthcare Materials 2014, 3 (1), 133-141. [3] Kulkarni, V. etc., Impact of ligand Structure on Biological Activity and Photophysical Properties of NHC-Protected Au13 Nanoclusters. J. Am. Chem. Soc 2025, 147 (5) 4017-4025. [4] Sullivan, A. etc. Diving into Unknown Waters: Water-Soluble Clickable Au13 Nanoclusters Protected with N-Heterocyclic Carbenes for Bio-Medical Applications. J. Am. Chem. Soc 2025, 147 (5) 4230-4238.", "source_company": "University of Toronto", "source_org_type": "大学", "row_number": 340, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "class I selective HDAC inhibitors", "company": "Cornell University", "org_type": "大学", "target": "HDAC1", "modality": "inhibitor", "importance_level": "低", "total_score": 47.5, "institution_score": 35, "track_score": 65, "milestone_score": 45, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "药物为class I选择性HDAC抑制剂，主要靶向HDAC1，在胰腺癌代谢脆弱性中显示作用。机构为大学，preclinical机制研究阶段，赛道非最热门，总分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9118", "id": "SFXM_5wBX1NQZOEH-LG5", "source_drug_name": "class I selective HDAC inhibitors", "title": "Targeting HDAC1 activity presents vulnerabilities in pancreatic cancer metabolism", "abstract_text": "Pancreatic cancer is a lethal disease with significant metabolic reprogramming, which promotes tumor growth, therapy resistance, and adaptation to stress. These alterations are largely attributed to mutations in the KRAS oncogene but with limited progress in therapeutic discovery. Despite the recent focus on metabolism in pancreatic cancer, the major mediators of altered metabolism remain unknown. Our differential gene expression analyses in multiple patient cohorts’ pancreatic tumors versus normal tissues identify histone deacetylase 1 (HDAC1) as a consistently upregulated epigenetic gene. HDAC1-high tumors correlate strongly with metabolic pathways, including glycolysis, redox metabolism, and nucleotide biosynthesis. Using CRISPR/Cas9 gene editing, we found that the deletion of HDAC1 in pancreatic cancer cell lines triggers metabolic shifts, notably in glucose metabolism, and led to a distinct growth phenotype in a cell context-dependent manner. Similarly, treatment with class I selective HDAC inhibitors was selectively effective in suppressing pancreatic cancer cell growth. Furthermore, our drug screenings demonstrate profound synergies that overlap across the HDAC1-deleted and HDACi treated cell lines that present under-explored avenues for therapeutics. Our data provides evidence of compensatory metabolic alterations upon HDAC1 inhibition, which could broaden the opportunities for therapeutic intervention in pancreatic cancer.", "source_company": "Cornell University", "source_org_type": "大学", "row_number": 359, "target_meta": "HDAC1", "MOA_meta": "抑制剂"}, {"drug_name": "fully human monoclonal antibodies (mAbs) that prevent the proteolytic cleavage of the transforming growth factor-beta (TGFβ) type I receptor (TβRI)", "company": "Umeå University", "org_type": "大学", "target": "TβRI cleavage (ADAM17-mediated)", "modality": "mAb", "importance_level": "低", "total_score": 47.5, "institution_score": 30, "track_score": 65, "milestone_score": 60, "field_heat_score": 50, "bonus_score": 3, "brief_reason": "该抗体靶向阻断ADAM17介导的TβRI裂解以抑制TβRI-ICD核转位和CRPC转移，机制新颖但靶点非热门。大学机构研发、仅preclinical小鼠模型有效（类似docetaxel）、无商业推进迹象导致总体评分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5657", "id": "eVXM_5wBX1NQZOEH-LG5", "source_drug_name": "fully human monoclonal antibodies (mAbs) that prevent the proteolytic cleavage of the transforming growth factor-beta (TGFβ) type I receptor (TβRI)", "title": "Targeting oncogenic TBRI signaling inhibits androgen-independent prostate cancer growth and metastasis", "abstract_text": "Metastatic castration-resistant prostate cancer (mCRPC) remains the primary cause of prostate cancer-related mortality. Despite available treatments, the molecular mechanisms underlying tumor invasion and metastasis are not fully understood, highlighting the need for novel therapeutic strategies. In this study, we developed fully human monoclonal antibodies (mAbs) that prevent the proteolytic cleavage of the transforming growth factor-beta (TGFβ) type I receptor (TβRI) by steric hindrance. This cleavage, mediated by the metalloprotease ADAM17 (a disintegrin and metalloprotease domain 17), also known as TACE, results in the generation of a soluble intracellular domain (TβRI-ICD) that translocates to the nucleus of castration-resistant prostate cancer (CRPC) cells and promotes epithelial-to-mesenchymal transition (EMT), invasion, and metastasis. High levels of TGFBR1 were found to correlate with poor survival in two independent clinical cohorts of patients with mCRPC, and a strong positive association between TGFBR1 and ADAM17 expression was observed. In a preclinical human mCRPC mouse model, treatment with our therapeutic mAbs effectively prevented nuclear accumulation of TβRI-ICD, inhibited EMT, and suppressed tumor growth, invasion, and metastasis. Notably, the therapeutic effect was comparable to that of docetaxel, a current standard-of-care chemotherapy, and without noticeable side effects. These findings suggest that targeting TβRI cleavage using specific mAbs offers a novel precision medicine approach for mCRPC. By selectively blocking the pro-metastatic activity of TβRI-ICD without disrupting physiological TGFβ signaling, this strategy may provide a safer and more effective alternative to existing therapies for advanced prostate cancer.", "source_company": "Umeå University", "source_org_type": "大学", "row_number": 390, "target_meta": "ADAM17", "MOA_meta": "单抗"}, {"drug_name": "CRY1 inhibitor", "company": "Korea Univ. College of Medicine", "org_type": "大学", "target": "CRY1", "modality": "inhibitor", "importance_level": "低", "total_score": 47.5, "institution_score": 25, "track_score": 75, "milestone_score": 45, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "CRY1抑制剂通过逆转NANOG高表达肿瘤的免疫耐药机制，与anti-PD-1及CTL过继治疗协同显著抑制肿瘤生长。大学机构得分较低，但靶点新颖且具有潜在翻转免疫治疗耐药的机制价值，整体仍处于preclinical概念验证阶段。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9419", "id": "qFXM_5wBX1NQZOEH-LK6", "source_drug_name": "CRY1 inhibitor", "title": "Cry1 inhibition reverses resistance to T cell-based immunotherapy by promoting anti-tumor immunity", "abstract_text": "T cell-based immunotherapy, including immune checkpoint blockade (ICB), has dramatically changed the paradigm of cancer treatment. However, many cancer patients do not achieve durable responses to immunotherapy, and resistance to these treatments remains a major clinical challenge. We previously showed that immune pressure imposed by immunotherapy selects for immune-resistant tumors that acquire both tumor cell-intrinsic and tumor cell-extrinsic refractoriness through NANOG-driven transcriptional upregulation of HDAC1. In this study, we identify CRY1 as a pivotal NANOG-dependent effector that integrates these refractory traits. In NANOGhigh tumor cells, CRY1 stabilizes Cyclin A and MCL1, thereby promoting cancer stem cell-like properties and resistance to cytotoxic T lymphocyte (CTL)-mediated killing, a process that depends on HDAC1-mediated epigenetic silencing of APC3 and TRIM17. In parallel, CRY1 suppresses CXCL10 expression via HDAC1-dependent transcriptional repression, leading to reduced recruitment of CD8+ T cells into the tumor microenvironment (TME). Importantly, pharmacological inhibition of CRY1 synergizes with anti-PD-1 antibody treatment and adoptive CTL transfer to reduce tumor growth by converting immune-resistant tumors into an immune-sensitive state. Thus, our findings implicate CRY1 as a central molecular target for controlling NANOGhigh tumors and provide a rationale for combining CRY1 inhibitors with T cell-based immunotherapy to reverse the complex refractoriness of tumors.", "source_company": "Korea Univ. College of Medicine", "source_org_type": "大学", "row_number": 593, "target_meta": "CRY1", "MOA_meta": "抑制剂"}, {"drug_name": "APC (CD24-Ab-TG2-BP)", "company": "Indiana University School of Medicine", "org_type": "大学", "target": "TG2/CD24", "modality": "other", "importance_level": "低", "total_score": 47.5, "institution_score": 25, "track_score": 65, "milestone_score": 55, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "APC为CD24抗体与TG2抑制肽的首创抗体-肽偶联物，同时靶向TG2-CD24相互作用以破坏卵巢癌干细胞特性及微环境交互。大学机构基础研究背景+preclinical阶段显著抑瘤及抗转移数据，但modality非主流热门赛道且机构非产业化头部导致总体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/719", "id": "5lXM_5wBX1NQZOEH-LK6", "source_drug_name": "APC (CD24-Ab-TG2-BP)", "title": "The functional crosstalk between tissue transglutaminase (TG2) and CD24 enhances cancer stem cell traits and therapy resistance in high grade serous ovarian cancer", "abstract_text": "High-grade serous ovarian cancer (HGSOC) remains one of the most lethal gynecologic malignancies, largely due to persistent cancer stem cells (CSCs) that drive disease progression. Our data revealed that tissue transglutaminase 2 (TG2) is a central mediator of OCSC biology through its interaction with fibronectin (FN) and integrins, activating oncogenic pathways, including Wnt signaling, that promote stemness and platinum resistance. We further identified that TG2 cooperates with the immune-regulatory receptor CD24 to anchor OCSCs to peritoneal organs, facilitating early metastatic implantation and ascites formation. To therapeutically disrupt this axis, we synthesized a selective peptide inhibitor (BP) that blocks the TG2-FN interaction and developed a CD24-neutralizing antibody (CD24-Ab), each of which suppresses CSC function in preclinical models. We then combined these modalities into a single first-in-class antibody-peptide conjugate, APC (CD24-Ab-TG2-BP), designed to simultaneously disrupt CD24 signaling and TG2-mediated CSC-tumor microenvironment (TME) interactions. TCGA analysis of HGSOC revealed TG2 and CD24 mRNA amplification in 3% and 2% of cases, respectively. Flow cytometry confirmed robust TG2 (58%, 51%) and CD24 (98%, 100%) expression, with substantial co-expression (55%, 45%) in OVCAR4 and OVCAR5 cells, respectively. APC treatment significantly downregulated CSC-associated markers (NANOG, OCT4, SOX2, ALDH1A1) and disrupted spheroid architecture. Co-immunoprecipitation demonstrated a specific TG2-CD24 interaction in SKOV3 and OVCAR4 cells, while biochemical fractionation localized the complex to lipid raft microdomains, signaling platforms that integrate receptors and downstream oncogenic effectors. In OC xenograft models, treatment with APC significantly reduced tumor volume (0.22 ± 0.11 mm³ vs. 1.7 ± 1.1 mm³; N =5, P < 0.001), tumor weight (0.64 ± 0.21 gm vs. 1.53 ± 0.46 gm; N =5, P < 0.01), and metastasis (5.3 + 3.6 vs. 10 + 3.6; N =5, P < 0.001) when compared with IgG controls, thus demonstrating potent anti-tumor efficacy. Collectively, these findings identify a lipid raft-restricted TG2-CD24 complex as a novel driver of OCSC maintenance and chemoresistance in HGSOC. Targeting this interaction with APC effectively disrupts CSC-TME crosstalk and suppresses tumor progression, establishing TG2/CD24 axis as a novel therapeutic vulnerability for overcoming resistance and recurrence in HGSOC.", "source_company": "Indiana University School of Medicine", "source_org_type": "大学", "row_number": 636, "target_meta": "TGM2,CD24", "MOA_meta": "其他"}, {"drug_name": "novel molecular glues", "company": "Fox Chase Cancer Center", "org_type": "医院", "target": "p120RasGAP/Ras complex", "modality": "molecular glues", "importance_level": "低", "total_score": 47.5, "institution_score": 25, "track_score": 85, "milestone_score": 35, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "药物为新型分子胶，通过AI/ML设计增强p120RasGAP与Ras的结合以抑制NF1缺失细胞中Ras信号通路。机构为医院/研究型，得分较低，但分子胶+KRAS相关通路具有较高赛道热度，目前仅初步体外验证，开发阶段早期。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5715", "id": "8VXM_5wBX1NQZOEH-LK6", "source_drug_name": "novel molecular glues", "title": "Use of a p120 RasGAP glue to inhibit KRas in NF1-null cells", "abstract_text": "Neurofibromatosis type 1 (NF1) is an autosomal dominant genetic disorder that is associated with a spectrum of pathologies including glioma, autism spectrum disorder, Lisch nodules of the iris and neurofibroma. The NF1 gene encodes neurofibromin, a Ras GTPase-activating protein. Deletion or disabling mutations in NF1 gene result in an absence of neurofibromin and sustained Ras activation, driving uncontrolled cell proliferation and tumorigenesis. Targeting the Ras protein directly has until recently proved challenging due to the lack of binding cavities on molecular surface and due to its high affinity for GTP/GDP.\nPurpose: Our study aims to evaluate the efficacy of novel molecular glues designed to modulate Ras activity by increasing its binding to p120RasGAP, a ubiquitously expressed negative regulator of Ras that, like NF1, augments the GTPase activity of Ras, assisting its conversion from active Ras-GTP to inactive, Ras-GDP. The goal is to use these compounds to enable p120RasGAP to functionally replace neurofibromin in NF1-deficient cells, restoring normal Ras signaling.\nMethods: We used an artificial intelligence/machine learning (AI/ML) protocol to identify potential molecular glues that should stabilize the p120RasGAP/Ras complex. To assess the impact of these compounds, we used NF1-deficient cell line and employed Western Blot analysis to measure changes in phosphorylated ERK (p-ERK) levels as a downstream marker of Ras activity. In addition, we used shRNA-mediated knockdown of the RASA1 gene, which encodes p120RasGAP protein, to verify whether the observed effects are dependent on the proposed Ras/RasGAP interaction mechanism. To assess direct interaction, purified recombinant KRAS and p120RasGAP were used in AlphaScreen binding assay. Compound binding was further validated by surface plasmon resonance (SPR).\nResults: Preliminary data indicate a reduction in p-ERK levels upon treatment with novel compounds, suggesting partial suppression of Ras signaling. Furthermore, in p120RasGAP knockdown cells, the molecular glues had a less potent effect in reducing p-ERK levels, suggesting that our compounds act through the proposed mechanism rather than producing off-target effects. Of the three most perspective candidates, one promoted significant binding of KRAS to p120RasGAP in an AlphaScreen assay. This result was also confirmed by SPR.\nConclusion: AL/ML methods can be used to design molecular glues that stabilize the interaction of p120RasGAP to Ras, providing a promising avenue for targeted NF1 therapies. Such compounds might be useful in reducing Ras activity in NF1-mutant cells. We aim to further characterize this interaction using STD NMR and initiate crystallization trials to determine the structural basis of binding.", "source_company": "Fox Chase Cancer Center", "source_org_type": "医院", "row_number": 644, "target_meta": "RasGAP,Ras", "MOA_meta": "分子胶"}, {"drug_name": "lipid-raft-targeted sphingosine delivery system", "company": "Tianjin Medical Univ. Cancer Inst. & Hospital", "org_type": "医院", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 47.5, "institution_score": 35, "track_score": 65, "milestone_score": 45, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "该递送系统通过靶向脂筏递送鞘氨醇增强免疫激活和消化系统肿瘤新辅助治疗敏感性，但靶点未明确披露。机构为国内医院学术单位、仍处概念验证阶段导致综合评分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/7519", "id": "P1XM_5wBX1NQZOEH-LO6", "source_drug_name": "lipid-raft-targeted sphingosine delivery system", "title": "Sphingomonas-driven sphingosine signalling enhances neoadjuvant therapy responses in digestive system cancers", "abstract_text": "Neoadjuvant therapy (NAT) is becoming an essential component in the management of digestive system malignancies, yet whether the microbiome modulates NAT efficacy remains unclear. Here, we profile the intratumoral microbiome of patients with digestive system cancers following NAT and identify Sphingomonas as markedly enriched in pancreatic ductal adenocarcinoma (PDAC) tumors from responders. Sphingomonas was likewise detected in gastric and colorectal cancers with favourable NAT responses. Using mouse models, we show that Sphingomonas stably colonizes pancreatic, gastric, and colorectal tumors and augments NAT efficacy through secretion of sphingosine. Mechanistically, Sphingomonas-derived sphingosine binds lipid raft structures on the plasma membrane and is preferentially internalized by immune cells, where it selectively activates the ceramide-sphingomyelin synthetic pathway rather than the Sphingosine-1-Phosphate (S1P) pathway. This process amplifies lipid raft organization, promotes immune synapse formation, and enhances immune-mediated tumor cell killing. We further develop a lipid-raft-targeted sphingosine delivery system that boosts immune activation and sensitizes tumors to NAT. Together, these findings uncover a previously unrecognized microbial determinant of NAT responsiveness in digestive system cancers and provide a conceptual and translational framework for microbiome-based patient stratification and therapeutic sensitization.", "source_company": "Tianjin Medical Univ. Cancer Inst. & Hospital", "source_org_type": "医院", "row_number": 697, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "immune checkpoint blockade", "company": "UT MD Anderson Cancer Center", "org_type": "医院", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 47.5, "institution_score": 35, "track_score": 80, "milestone_score": 30, "field_heat_score": 85, "bonus_score": 0, "brief_reason": "该记录研究的是免疫检查点阻断（ICB）在MSI-H胃肠癌中的响应机制与空间转录特征，而非披露具体新药或靶点；机构为顶级肿瘤医院但非drug developer，研究属基础-转化性质而非药物开发里程碑，故整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10753", "id": "YVXM_5wBX1NQZOEH-LO6", "source_drug_name": "immune checkpoint blockade", "title": "Spatially organized transcriptional programs and tumor-stroma interfaces shape immunotherapy response in microsatellite instability-high gastrointestinal cancers", "abstract_text": "Background: Immune checkpoint blockade (ICB) has significantly improved outcomes in microsatellite instability-high (MSI-H) gastrointestinal cancers, yet more than half of patients do not achieve durable remission despite initial tumor regression. Clinical decisions guided solely by MSI status and radiographic response provide limited ability to anticipate long-term benefit or inform choices regarding surgery and treatment modification. The development of spatially informed molecular predictors of sustained response would therefore address a critical unmet need in the management of MSI-H tumors.\nMethods: Spatial transcriptomic profiling was performed on 18 tumor specimens from 13 patients with gastric, colorectal, or esophageal cancers, including 11 MSI-H and 2 MSS tumors, collected before and after ICB therapy. All tissues were assayed using the 10x Genomics Visium platform. Pathology-guided spot annotation was combined with transcriptional Meta-program analysis, spatial deconvolution, niche interaction mapping, and ligand-receptor modeling to characterize tumor-immune-stromal organization across sustained complete responders (CR) and non-sustained responders (NR).\nResults: We found that tumor cell meta-programs (MPs) exhibited distinct spatial gradients across different response groups. The epithelial-mesenchymal transition MPs was enriched at the invasive margin of pre-treatment NR (pre-NR) tumor tissue and diminished toward the core, while the Cycling-high-Interferon MPs peaked at the periphery of pre-CR tumor tissue. These findings indicate that transcriptional programs are spatially compartmentalized within the tumor. Next, we investigated how the spatial organization of the tumor microenvironment (TME) differed between response groups. In pre-CR tumors, malignant cells colocalized with B cells and T follicular helper cells within tertiary lymphoid structures (TLSs), whereas in pre-NR tumors, they were associated with macrophages and cancer-associated fibroblasts. Notably, TLSs from CR tumors exhibited stronger immune activation signatures irrespective of their maturation state. Cell-cell communication analysis further revealed immune activation at the tumor-stroma interface in sustained-CR tumors, contrasting with immunosuppressive signaling in NR tumors.\nConclusions: Our study reveals distinct spatial and transcriptional programs underlying differential responses to ICB in MSI-H gastrointestinal cancers, highlighting the pivotal role of tumor-immune-stromal organization in shaping therapeutic outcomes and guiding future strategies to enhance immunotherapy efficacy.", "source_company": "UT MD Anderson Cancer Center", "source_org_type": "医院", "row_number": 715, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "PI3Kδ inhibitors", "company": "University College London", "org_type": "大学", "target": "PI3Kδ", "modality": "inhibitor", "importance_level": "低", "total_score": 47.5, "institution_score": 35, "track_score": 65, "milestone_score": 45, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "PI3Kδ抑制剂针对实体瘤细胞内在功能的研究，靶点为PI3Kδ，主要机制为探讨免疫治疗中肿瘤细胞自身受抑的影响。机构为大学非商业研发，处于preclinical基础研究阶段，无明确临床里程碑，赛道PI3Kδ在实体瘤领域热度有限，导致整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8764", "id": "kVXM_5wBX1NQZOEH-LO6", "source_drug_name": "PI3Kδ inhibitors", "title": "Solid tumor cell-intrinsic function of PI3Kδ", "abstract_text": "PI3Kδ is a predominantly leukocyte-enriched class I PI3K consisting of the p110δ catalytic subunit (encoded by PIK3CD) and most commonly the p85α regulatory subunit (encoded by PIK3R1). PI3Kδ is an important regulator of B-cell function and has been the target of extensive drug development efforts for B-cell malignancies, with multiple inhibitors approved for this indication. Based on our pre-clinical studies, PI3Kδ inhibition is now also emerging as an immunotherapy approach for solid tumours. Regulatory T-cells (Treg) are exquisitely sensitive to PI3Kδ inhibition, therefore pharmacological PI3Kδ inhibitors preferentially target the Tregs, rebalancing the immune system in favour of an effector T cell-mediated anti-tumour immune response. This concept is currently under investigation in clinical trials in uveal melanoma and non-small cell lung cancer. Notably, we and others have also observed multiple solid tumour types including glioblastoma, melanoma, breast cancer, prostate cancer, neuroblastoma and hepatocellular carcinoma also express wild-type PIK3CD, often at much higher levels than their non-transformed cell types of origin. Some studies suggest PI3Kδ promotes proliferation in these tumour cells, but this remains unclear with the potential that inhibitors were used at non-PI3Kδ-specific concentrations, and these findings are not consistently confirmed with genetic approaches. This raises the questions of what function PI3Kδ plays in solid tumours and how the use of PI3Kδ inhibitors for immunotherapy will affect the tumour cells themselves via inhibition of cell-intrinsic PI3Kδ. Using highly-selective PI3Kδ inhibitors and CRISPR-Cas9-mediated PIK3CD deletion in solid tumour cell lines, we demonstrate that PI3Kδ inhibition does not affect cell proliferation in these models. However, through both in vitro and xenograft studies, we have identified cancer-relevant roles for PI3Kδ in solid tumours, the implications of which will be presented. Our data suggest the solid tumour cell-intrinsic PI3Kδ expression should be considered to inform PI3Kδ-targeting immunotherapy studies.", "source_company": "University College London", "source_org_type": "大学", "row_number": 746, "target_meta": "PI3Kδ", "MOA_meta": "抑制剂"}, {"drug_name": "DM1", "company": "IEO - European Institute of Oncology", "org_type": "研究机构", "target": "微管 (microtubule)", "modality": "inhibitor", "importance_level": "低", "total_score": 47.5, "institution_score": 35, "track_score": 65, "milestone_score": 45, "field_heat_score": 60, "bonus_score": 2, "brief_reason": "DM1为maytansinoid类微管抑制剂，在NF1缺陷HER2+乳腺癌模型中显示更强敏感性，机制与未修复的微管晶格损伤相关。研究机构非商业主体、纯机制探索且preclinical层面限制整体重要性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3488", "id": "xFXM_5wBX1NQZOEH-LO6", "source_drug_name": "DM1", "title": "Quantitative analysis of microtubule lattice damage in NF1-deficient HER2-positive breast cancer under mitotic and pharmacological stress", "abstract_text": "Our understanding of microtubule (MT) dynamics has recently expanded to include remodeling events within the lattice, where mechanical stress generates discontinuities repaired through intra-lattice tubulin incorporation and EB1 redistribution. Only two factors, CLASP1 and SSNA1, are known to recognize and modulate this form of MT damage. Methods to reliably estimate MT damage and repair are not established, leaving their contribution to tumorigenesis and anticancer drug activity unclear. In our previous work, we demonstrated that loss of the tumor suppressor NF1, a new MT-associated protein (MAP), leads to increased MT damage in HER2-positive breast cancer cells. This in turn causes mitotic defects (potentially contributing to tumorigenesis) but also sensitization to maytansinoids like DM1, a drug class frequently used in Antibody-Drug Conjugates (ADC, T-DM1 and Mirvetuximab Soravtansine). To investigate MT damage and repair upon pharmacological and mechanical stress, we analyzed the distribution of EB1, normally confined to growing MT tips but known to redistribute along the MT body upon structural disruption or when repair factors like CLASP are ablated. We developed a novel method to systematically quantify EB1 and tubulin signal along single MTs. To achieve the spatial precision required to resolve EB1 we combined DeepSIM and expansion microscopy (ExM) with two complementary analytical strategies: manual 3D MT tracing using SNT ImageJ plugin (designed for neurite tracing) and an automated pipeline for MT segmentation and EB1 signal extraction. Upon DM1 treatment, EB1 showed progressive re-localization from the tip to the MT body, consistent with partial intra-lattice disruption in addition to its established de-polymerizing activity at the tip. In NF1 deficient cells, an initial increase in intra-lattice EB1 was followed by a sharp reduction in overall EB1 signal and pronounced MT fragmentation, indicating faster DM1-induced MT fracturing and depolymerization; this was abolished by NF1 re-expression. These results directly show how failed MT repair, more prominent in NF1 deficient cells, creates further intra-lattice DM1 binding sites explaining increased sensitivity. In mitosis, NF1 deficient cells showed strongly increased EB1 signal on the MT shaft, consistent with failure of repair under strong mechanical stress. EB1 shaft localization and mitotic defects (chromosome missegregation, aneuploidy) were rescued by NF1 re-expression.By establishing a quantitative framework to measure EB1 redistribution at single MT resolution, our study provides a previously unavailable strategy to monitor intra-lattice damage in cancer cells. These findings establish for the first time a direct causative link between unrepaired MT damage and chromosomal instability, providing a new model to understand maytansinoid mechanism of action.", "source_company": "IEO - European Institute of Oncology", "source_org_type": "研究机构", "row_number": 785, "target_meta": "microtubule", "MOA_meta": "抑制剂"}, {"drug_name": "H279", "company": "Cedars-Sinai Medical Center", "org_type": "医院", "target": "STAT3", "modality": "inhibitor", "importance_level": "低", "total_score": 47.5, "institution_score": 35, "track_score": 65, "milestone_score": 45, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "H279为小分子STAT3抑制剂，可抑制肿瘤促炎轴并诱导PDAC和TNBC细胞凋亡。机构为医院类型、处于preclinical阶段且无明确临床里程碑，综合热度一般导致总分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8821", "id": "KFXM_5wBX1NQZOEH-LS6", "source_drug_name": "H279", "title": "Small molecules inhibited dysregulated STAT3-proinflammatory axis and induced antitumor responses in pancreatic and breast cancer", "abstract_text": "Signal transducer and activator of transcription 3 (STAT3) is a promising anti-cancer therapeutic target that promotes tumor development and progression. To study the STAT3-specific mechanisms underpinning tumor formation and that underlie the responses to its targeting, we used the validated mutant KrasG12D (KC) mice that under high-fat diet (HFD) has a high pancreatic adenocarcinoma (PDAC) incidence and progression, human cancer-associated fibroblasts (CAFs), PDAC and triple-negative breast cancer (TNBC) cells and xenograft models and interrogated STAT3 activity with two small molecule inhibitors, H182 and H279. Human CAFs, PDAC and TNBC cells harboring aberrantly-active STAT3 responded to growth factor and cytokine stimulation by further enhancing phospho-tyrosine-STAT3 (pYSTAT3) levels. Likewise, upon feeding KC mice the HFD, pYSTAT3 was strongly increased in cells that tracked along a path of altered phenotype, including acinar-ductal-metaplasia (ADM) elements, neoplastic ducts, stromal and immune cells, but was not present in normal acinar cells, in parallel with the development of pancreatic intraepithelial neoplasia (PanIN) lesions. To define the contexts of the pYSTAT3 and the phenotype changes, we probed the cells and mouse models with the inhibitors. The pYSTAT3 levels in the cells were suppressed early by H182 and H279 treatment. In PDAC cells, prolonged treatments with H182 severely shifted the secretome, including decreased IL-6-stimulated production of IL-8, SERPINE1, CXCL1, CXCL12, CCL2 and MIF, repressed the expression of genes involved in immune evasion, angiogenesis, cell proliferation, migration, oxidative stress and tumor progression, and upregulated tumor suppressor genes. In PDAC or TNBC cells, similar prolonged treatments with H182 or H279 also suppressed the expression of anti-apoptotic Mcl-1, Bcl-xL and c-Myc, pro-invasive matrix metalloproteinase 9, and the epithelial-mesenchymal transition proteins, SNAIL, Twist, Snug and ZEB, while inducing E-cadherin and pro-apoptotic Bax, Bad, PUMA and BIM. Treatments of PDAC and TNBC cells with the inhibitors also led to DNA damage, γH2AX, ATM and Chk2 induction, mitochondrial oxygen consumption rate impairment, cell cycle arrest at the G2/M phase, decreased viability, migration and invasiveness in vitro, and apoptosis. H182 treatment prevented acinar cell de-differentiation into ADM/PanINs, in parallel with decreased pro-fibroinflammatory gene expression in the pancreas, such as CXCL12, CCL2, and CCL5 in HFD-fed KC mice, and inhibited growth of PDAC subcutaneous xenografts in mice. Together, the findings support a hyperactivated STAT3-pro-fibroinflammatory cytokines and chemokines axis in diverse cell types within tumors that is critical in tumor initiation and progression. Inhibiting STAT3 functions may be a preventative and therapeutic approach against cancer.", "source_company": "Cedars-Sinai Medical Center", "source_org_type": "医院", "row_number": 859, "target_meta": "STAT3", "MOA_meta": "抑制剂"}, {"drug_name": "MARK2/3/4 hits", "company": "Yonsei University College of Medicine", "org_type": "大学", "target": "MARK2/MARK3/MARK4", "modality": "inhibitor", "importance_level": "低", "total_score": 47.5, "institution_score": 35, "track_score": 65, "milestone_score": 45, "field_heat_score": 55, "bonus_score": 0, "brief_reason": "药物为针对MARK2/3/4激酶的候选抑制剂（hit-compound阶段），机制通过抑制Hippo通路负调控因子以降低YAP/TAZ活性。大学机构+早期hit阶段导致整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4403", "id": "fJ7ECZ0BZznHJdntvNYd", "source_drug_name": "MARK2/3/4 hits", "title": "MARK2/MARK3/MARK4 kinases are therapeutic targets for human head and neck squamous cell carcinoma with co-dependencies of YAP-TEAD pathway", "abstract_text": "Background: Head and neck squamous cell carcinoma (HNSCC) requires the identification of new therapeutic targets to improve treatment outcomes. This study investigated the biological significance of Microtubule Affinity-Regulating Kinases (MARKs), a family of serine-threonine kinases that regulate microtubule-associated proteins (MAPs). Because MARK activity influences cell structure, intracellular transport, and proliferation, these kinases may represent promising therapeutic targets.\nMaterials and Methods: Protein expression levels of MARK family genes were evaluated in 20 human HNSCC cell lines. Cisplatin and docetaxel-resistant models were established by gradually escalating cisplatin and docetaxel concentrations up to 4 μM and 15 nM, respectively in CA9-22 and YD-8 cells. Cell viability was determined using WST assays. CRISPR/Cas9 genome editing was employed to generate MARK2/3/4 knockout cell lines. In addition, the anticancer efficacy of several newly developed MARK2/3/4 hits was assessed.\nResults: MARK2/3/4-knock-out cells demonstrated significantly reduced proliferation and impaired matrigel invasion compared with wild-type controls. MARK kinase loss was associated with suppression of the MAPK- and PI3K-AKT signaling pathways. Because MARK proteins are known to interfere with MST/SAV and LATS complex formation through phosphorylation-dependent mechanisms, we further showed that MARK4 depletion reduced nuclear YAP/TAZ localization and decreased expression of YAP/TEAD transcriptional targets. Collaborative screening identified multiple candidate molecules for MARK-specific inhibition at the hit-compound stage; notably, one lead compound exhibited strong antiproliferative activity in HNSCC cells, including cisplatin-resistant models.\nConclusions: MARK proteins function as negative regulators of the HIPPO kinase cascade, thereby enhancing YAP/TAZ oncogenic activity in HNSCC. Loss of MARK function reduces tumorigenic phenotypes, supporting MARKs as promising therapeutic targets for future drug development.", "source_company": "Yonsei University College of Medicine", "source_org_type": "大学", "row_number": 968, "target_meta": "MARK2,MARK3,MARK4", "MOA_meta": "抑制剂"}, {"drug_name": "SMC-101-017", "company": "Samsung Medical Center", "org_type": "医院", "target": "VEGFR2/TIE2", "modality": "inhibitor", "importance_level": "低", "total_score": 47.5, "institution_score": 35, "track_score": 65, "milestone_score": 45, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "SMC-101-017为双靶点VEGFR2/TIE2小分子抑制剂，基于片段重组设计，在骨肉瘤细胞系显示选择性时间-剂量依赖性细胞毒性，优于多激酶抑制剂。机构为医院而非药企、仍处体外筛选早期阶段导致总体评分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8923", "id": "b57M_5wBZznHJdnt_W3O", "source_drug_name": "SMC-101-017", "title": "Fragment-recombination design of a dual VEGFR2/TIE2 inhibitor with sarcoma-selective cytotoxicity", "abstract_text": "Sarcomas have limited systemic options beyond cytotoxic chemotherapy. VEGFR-directed multi-kinase inhibitors such as regorafenib provide modest benefit, but their broad RTK inhibition constrains the therapeutic margin. Because VEGFR2 and TIE2 are central regulators of tumor angiogenesis and vascular stability, we hypothesized that selective dual VEGFR2/TIE2 inhibition would improve potency while reducing off-target toxicity. We applied fragment recombination of validated RTK inhibitor scaffolds, combined with dual VEGFR2/TIE2 docking and phenotypic screening, to design candidate inhibitors with an improved potency-selectivity balance for sarcoma therapy. We computationally designed ~300 dual VEGFR2/TIE2 candidates via fragment recombination and synthesized 15 prioritized by docking and binding-site analyses. Antiproliferative activity was evaluated by MTS assay at 24 and 48 h (2.5-10 µM) in human osteosarcoma lines (143B, MG63, KHOS/NP, U-2 OS) and murine macrophages (RAW264.7) to assess myeloid cell toxicity. Lead compounds were compared with pazopanib, regorafenib, and sorafenib. At 2.5 µM (48 h), pazopanib, regorafenib, and sorafenib maintained ≥100% viability across all sarcoma lines. At 10 µM, pazopanib and regorafenib showed ≥80% viability, while sorafenib reduced 143B viability to 55% but spared other lines (≥80%). Among synthesized candidates, SMC-101-008 and SMC-101-011 showed early activity at 2.5 µM, reducing 143B and MG63 viability to 57-65% (24 h) and 47-84% (48 h). However, at 10 µM (48 h), both compounds also ablated RAW264.7 (1% viability), indicating loss of selectivity at higher doses. In contrast, SMC-101-017 exhibited time- and dose-dependent sarcoma-selective activity. At 2.5 µM, minimal activity was observed at 24 h (≥88% viability), but by 48 h, KHOS/NP and 143B viability dropped to 39% and 19%, respectively, while RAW264.7 remained unaffected (>100%). At 10 µM, SMC-101-017 showed moderate early suppression (66-72% viability across all lines at 24 h) but selectively eliminated KHOS/NP and 143B by 48 h (25% and 7%, respectively) while preserving RAW264.7 viability (>100%) SMC-101-017 demonstrated potent, time-dependent cytotoxicity against osteosarcoma while sparing myeloid cells across a 4-fold dose range, distinguishing it from approved multi-kinase TKIs. These findings nominate SMC-101-017 for target validation and in vivo evaluation, and support fragment-based design for developing kinase inhibitors with improved therapeutic windows.", "source_company": "Samsung Medical Center", "source_org_type": "医院", "row_number": 1024, "target_meta": "VEGFR2,TIE2", "MOA_meta": "抑制剂"}, {"drug_name": "DGKα inhibitors", "company": "University of Alberta", "org_type": "大学", "target": "DGKα", "modality": "inhibitor", "importance_level": "低", "total_score": 47.5, "institution_score": 25, "track_score": 75, "milestone_score": 35, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "靶向DGKα的allosteric小分子抑制剂，通过AI辅助结构设计实现高选择性，机制新颖可增强抗肿瘤免疫。大学早期计算设计阶段，无实验验证，机构非药企导致总体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6426", "id": "l57M_5wBZznHJdnt_W3O", "source_drug_name": "DGKα inhibitors", "title": "Structure-guided discovery of potent and selective DGKα inhibitors for targeted cancer therapy", "abstract_text": "Introduction: Cancer remains a major cause of morbidity and mortality in North America. Diacylglycerol kinases (DGKs) are key regulators of lipid-mediated signaling, converting diacylglycerol (DAG) to phosphatidic acid (PA), two bioactive second messengers that orchestrate diverse cellular pathways. The DGK families comprise ten isoforms classified into five subtypes. Among these, DGKα—a type I isoform—plays critical roles in immune regulation, neuronal signaling, and membrane remodeling. In the context of cancer, DGKα enhances tumor cell proliferation and survival while suppressing cytotoxic T-cell and natural killer (NK) cell activity, thereby facilitating immune evasion. DGKα also promotes PD-L1 expression, further reinforcing tumor immune escape. Dysregulated DGKα signaling similarly contributes to immune dysfunction. To address these pathological roles, we aim to develop highly selective DGKα inhibitors by exploiting a distinct allosteric pocket to achieve precise and isoform-specific modulation of the enzyme.\nMethods: We generated high-confidence structural models of DGK isoforms including (α, β) using state-of-the-art AI prediction platforms, complemented by molecular dynamics (MD) simulations and binding free-energy methodologies. Structural models of DGKα and DGKβ were constructed in the presence of biologically relevant cofactors (ATP, Ca²⁺, Zn²⁺, Mg²⁺) to capture catalytically competent conformations. Each model underwent extensive validation through long-timescale MD simulations, and dominant conformational ensembles were extracted via clustering analyses. A generative-design pipeline was subsequently deployed to create and prioritize novel small-molecule inhibitors based on predicted potency, isoform selectivity, and physicochemical suitability. Top-ranked candidates were further interrogated through molecular docking, MD refinement, and free-energy calculations to characterize their binding poses.\nResults: The DGKα structural models demonstrated strong concordance with available in vitro data, supporting their suitability for downstream computational analyses. Molecular docking identified a previously uncharacterized allosteric pocket capable of accommodating the generative-AI-derived compounds. MM-PBSA analyses of MD trajectories provided binding free-energy estimates and revealed key residues that mediate ligand engagement and stabilize the inhibitor-protein complexes.\nConclusion: S532, L556, H606, Y558, and F559 mediate ligand recognition, enabling elucidation of the mechanistic basis that underlies the interactions of two lead chemotypes. Several designed molecules exhibit marked isoform selectivity, displaying substantially stronger predicted affinity for DGKα than for DGKβ. Together, these insights provide a structural framework for the rational development of selective DGKα inhibitors.", "source_company": "University of Alberta", "source_org_type": "大学", "row_number": 1052, "target_meta": "DGKα", "MOA_meta": "抑制剂"}, {"drug_name": "structure-guided small-molecule inhibitor of DHX8", "company": "The Institute of Cancer Research", "org_type": "研究机构", "target": "DHX8", "modality": "inhibitor", "importance_level": "低", "total_score": 47.5, "institution_score": 45, "track_score": 65, "milestone_score": 30, "field_heat_score": 50, "bonus_score": 3, "brief_reason": "靶点为DHX8（DEAH-box RNA helicase，参与mRNA剪接和HSF1应激调控），结构指导的小分子抑制剂，但摘要无具体内容，仅为preclinical早期概念。机构为知名学术研究机构而非头部药企，得分中等偏低；赛道为RNA helicase靶向新兴但非最热门，开发阶段初步无明确里程碑，导致总分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/603", "id": "qp7M_5wBZznHJdnt_W3O", "source_drug_name": "structure-guided small-molecule inhibitor of DHX8", "title": "Structure-guided small-molecule inhibition of DHX8, a DEAH-box RNA helicase involved in mRNA splicing", "abstract_text": "There is no abstract associated with this presentation.", "source_company": "The Institute of Cancer Research", "source_org_type": "研究机构", "row_number": 1069, "target_meta": "DHX8", "MOA_meta": "抑制剂"}, {"drug_name": "OSMR neutralizing antibody", "company": "Salk Institute", "org_type": "研究机构", "target": "OSMR", "modality": "neutralizing antibody", "importance_level": "低", "total_score": 47.5, "institution_score": 35, "track_score": 65, "milestone_score": 45, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "药物为OSMR中和抗体，靶向OSM-OSMR信号轴以重编程胰腺癌免疫抑制性肿瘤微环境。Salk Institute为研究机构而非商业公司、仍处preclinical机制探索阶段且无明确临床转化里程碑，导致整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9633", "id": "3p7M_5wBZznHJdnt_W3O", "source_drug_name": "OSMR neutralizing antibody", "title": "Targeting the OSM-OSMR signaling axis to reprogram the tumor microenvironment and overcome immune suppression in pancreatic cancer", "abstract_text": "Pancreatic ductal adenocarcinoma (PDA) is one of the deadliest malignancies, characterized by a dense, fibrotic, and immune‑excluded tumor microenvironment (TME) that resists current therapies. Emerging evidence implicates the Oncostatin M (OSM)-Oncostatin M receptor (OSMR) signaling axis, a member of the IL‑6 cytokine family, as a key driver of PDA progression through regulation of tumor-stroma-immune interactions. My research aims to define how OSM-OSMR signaling orchestrates the immune‑suppressive microenvironment in PDA and to evaluate whether its inhibition can reprogram tumors toward immune responsiveness.Spatial transcriptomics analysis of treatment‑naïve human PDA revealed high OSMR expression associated with cancer‑associated fibroblast (CAF) activation, stromal stiffness, and enrichment of macrophage and monocyte gene signatures, alongside reduced CD8⁺ T‑cell infiltration. Integrated transcriptomic analyses identified OSMR‑associated genes enriched for NF‑κB, JAK-STAT, and IFN‑γ pathways. Functional studies showed that OSM-OSMR signaling promotes PDA cell proliferation, migration, and invasion, while driving CAF activation and polarization of monocytes toward immunosuppressive CD163⁺/CD206⁺ macrophages. In ex vivo human PDA slice cultures, recombinant OSM enhanced proliferation and STAT3 phosphorylation, effects reversed by OSM or OSMR neutralizing antibodies.To dissect the underlying mechanisms, I employed CRISPR‑engineered OSMR knockout and rescue PDA cell lines, OSMR‑overexpressing CAFs, and 3D co‑cultures with monocyte‑derived macrophages, integrated with single‑cell RNA‑seq, phospho‑proteomics, and spatial transcriptomics. Parallel translational studies will test OSM/OSMR‑neutralizing antibodies in patient‑derived organoids, tumor slice cultures, and genetically engineered mouse models (GEMMs), alone or in combination with FDA‑approved chemotherapies. These studies will assess the effects of OSM-OSMR signaling on tumor growth, stromal remodeling, immune infiltration, and metastasis.By defining how OSM-OSMR signaling sustains PDA’s fibrotic and immune‑suppressive TME and establishing its therapeutic vulnerability, this work aims to develop rational strategies that reprogram the TME, enhance immunotherapy responsiveness, and improve outcomes for patients with pancreatic cancer.", "source_company": "Salk Institute", "source_org_type": "研究机构", "row_number": 1109, "target_meta": "OSMR", "MOA_meta": "抗体"}, {"drug_name": "xmot-shCpt1a", "company": "UNC Lineberger Comprehensive Cancer Center", "org_type": "医院", "target": "CPT1a", "modality": "shRNA", "importance_level": "低", "total_score": 47.5, "institution_score": 35, "track_score": 65, "milestone_score": 45, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "xmot-shCpt1a为携带Cpt1a靶向shRNA的exosome递送平台，沉默DC中CPT1a以抑制FAO和Treg生成，机制新颖但仅preclinical proof-of-principle。机构为大学附属癌症中心非商业化实体、开发阶段早期导致总分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10557", "id": "5Z7M_5wBZznHJdnt_W3O", "source_drug_name": "xmot-shCpt1a", "title": "Exosome-targeted xmot-shRNA as a modular platform to dissect signaling pathways driving tolerogenic dendritic cells in the tumor microenvironment", "abstract_text": "Dendritic cells (DCs) orchestrate tumor-targeted immunity and are essential for immune checkpoint inhibitor (ICI) efficacy, but ICI responses often fail when tumors drive DCs into a pro-tolerogenic state exhibiting an impaired capacity to stimulate CD8+ T cell activation and an enhanced ability to drive CD4+FoxP3+ regulatory T cell (Treg) differentiation. Despite the potent impact of DC tolerization on the generation of anti-tumor immunity, the pathways involved in their development in vivo are poorly understood. We have previously demonstrated that tolerogenic DCs in the tumor microenvironment maintain increased fatty acid oxidation (FAO) and this metabolic program fuels indoleamine-2,3-dioxygenase 1 (IDO1) activation and downstream Treg development. A pivotal check point in this pathway is the rate limiting enzyme, carnitine palmitoyltransferase 1a (CPT1a). Tumor-derived extracellular vesicles (EVs) are abundantly released in response to stress and can transfer regulatory RNAs to infiltrating immune cells. DCs are highly proficient at engulfing these EVs within tumors. A defined 3′ exosome-enriched motif (xmot) sequence can selectively load oligonucleotides into these vesicles, providing an opportunity to exploit tumor EV biogenesis for shRNA delivery. Here, we aimed to utilize the xmot-shRNA platform to selectively silence Cpt1a in DCs to suppress FAO and prevent Treg development.Cpt1a-targeted shRNA is fused to a 3′ exosome-enrichment trafficking motif and utilized to generate a xmot-shCpt1a-expressing BRAFV600E-PTEN-/- melanoma cell line. The tumor EVs were confirmed to harbor Cpt1a-shRNA by qrt-PCR and found to suppress both DC Cpt1a expression and DC oxidative phosphorylation in vitro. In order to track selective DC targeting in vivo, the platform was equipped with an EV-enriched CD81-mEmerald marker protein. Using this approach, mEmerald+ DCs infiltrating xmot-shCpt1a-expressing BRAFV600E-PTEN-/- melanomas were isolated by fluorescence-activated cell sorting and found to exhibit suppressed Cpt1a expression levels. By comparing with control BRAFV600E-PTEN-/- melanomas, this work demonstrated xmot-shCpt1a-expression to inhibit intra-tumoral CD4+FoxP3+ Treg accumulation, enhance tumor CD8+ T cell infiltration and activation, and suppress BRAFV600E-PTEN⁻/⁻ melanoma progression. Collectively, this study serves as a proof-of-principle for the xmot-shRNA/CD81-mEmerald platform as a modular delivery system for dissecting signaling pathways contributing to the development of tolerized DCs within the tumor microenvironment. This approach is now being utilized to probe additional regulatory circuits contributing to DC tolerization in vivo.", "source_company": "UNC Lineberger Comprehensive Cancer Center", "source_org_type": "医院", "row_number": 1113, "target_meta": "CPT1A", "MOA_meta": "shRNA疗法"}, {"drug_name": "PARP inhibitors", "company": "University of Pennsylvania", "org_type": "大学", "target": "PARP", "modality": "inhibitor", "importance_level": "低", "total_score": 47.5, "institution_score": 35, "track_score": 75, "milestone_score": 30, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "PARP抑制剂靶向PARP酶，已是gBRCA1/2突变TNBC标准治疗，但本次记录为大学机构的空间蛋白质组学基础研究而非药物开发。机构非企业、未披露新药里程碑导致总分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10777", "id": "957M_5wBZznHJdnt_W3O", "source_drug_name": "PARP inhibitors", "title": "A single-cell spatial proteomic analysis of the TNBC microenvironment defines genotype-specific features", "abstract_text": "Breast cancer in women with germline BRCA1/2 pathogenic variants (gBRCA1/2) are generally treated with platinum-based therapies and PARP inhibitors (PARPi) with resistance commonly emerging. As the tumor microenvironment (TME) in gBRCA1 triple-negative breast cancer (TNBC) is enriched with tumor-infiltrating lymphocytes (TILs) and CD8 T cells, treatment trials have been done combining PARPi and immune checkpoint inhibitors (ICIs) in BRCA1 TNBC. This combination has not been shown to be more effective than PARPi alone. Evaluating the TME in gBRCA1/2 TNBC may help identify tumors most likely to benefit from PARPi/ICI therapy. We performed a detailed spatial proteomic analysis to characterize tumor-immune cell interactions in patients with gBRCA1/2 and wild-type (WT) TNBC with spatial tissue multiplexing (PhenoCycler) in 101 gBRCA1, 24 gBRCA2, and 30 WT TNBCs with matched RNAseq for 34 gBRCA1, 8 gBRCA2, and 16 WT TNBCs. A 43-plex antibody panel was developed featuring markers of DNA damage and repair, immune subtypes and exhaustion. We detected single tumor cells (PANCK+) in S/G2 phase (Geminin+) with double-stranded DNA breaks (yH2AX+) and DNA repair capacity (RAD51+) across all three cohorts. gBRCA1/2 TNBC patients exhibited a significantly lower proportion of tumor cells with homologous recombination proficiency (HRP) (gBRCA1 p = 0.006; gBRCA2 p = 0.007) compared to WT TNBC. CD4 & CD8 T cells, and CD20 B cells had intact DNA repair in WT and gBRCA1/2 TNBC. The frequency of CD8+ T (p=0.016) and CD20 B (p=0.003) cells was significantly higher in gBRCA1 compared to WT TNBC; BRCA2 and WT TNBC showed no differences. A detailed characterization of CD8 T cells revealed significantly increased numbers of potentially dysfunctional CD8 T cells in BRCA1 (TOX, p<0.0001; LAG-3, p=0.028; PD-1, p=0.033) and BRCA2 (LAG-3, p=0.033) compared to WT TNBC. We observed two types of TMEs in gBRCA1 TNBC: 1) CD8 low (mean<9.38%) with 1.4-fold increased immune checkpoint (PD-1) expression (mean: 15.4%) and high DNA damage in tumor cells; and 2) CD8 high (>9.38%) with reduced PD-1 and low DNA damage in tumor cells. Our findings suggest that although gBRCA1/2 variants lead to DNA damage and impaired repair in tumor cells, T cells (CD4, CD8) and B cells (CD20) retain intact DNA repair mechanisms. We also found that gBRCA1/2 TNBCs exhibit higher levels of immune checkpoint proteins LAG-3 and PD-1 on CD8 T cells compared to WT TNBC. This finding suggests the potential utility of additional ICI (LAG-3, PD-1) beyond PD-L1 blockade. Importantly, patients with gBRCA1-associated TNBC exhibit two different TMEs, suggesting that the response to ICI- and DNA-damaging-based therapies may differ between tumors, and anticipated prior to treatment. Defining treatment-naïve TME is crucial for designing personalized, targeted ICI strategies for individuals with BRCA-mutated TNBC.", "source_company": "University of Pennsylvania", "source_org_type": "大学", "row_number": 1124, "target_meta": "PARP", "MOA_meta": "抑制剂"}, {"drug_name": "HPK", "company": "Cedars Sinai Medical Center", "org_type": "医院", "target": "HER3", "modality": "other", "importance_level": "低", "total_score": 47.5, "institution_score": 35, "track_score": 65, "milestone_score": 45, "field_heat_score": 60, "bonus_score": 2, "brief_reason": "HPK为HER3靶向的融合蛋白载体，用于递送蛋白质payload至HER3阳性肿瘤细胞，实现靶向蛋白递送。机构为医院/学术中心而非商业药企导致institution_score较低，preclinical阶段且无突破性临床里程碑，赛道为靶向递送平台有一定热度但非最热门modality，总分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4387", "id": "LJ7M_5wBZznHJdnt_W7O", "source_drug_name": "HPK", "title": "Nano-protomers targeted at tumor metastasis", "abstract_text": "Therapeutic failure in many highly aggressive cancers is often driven by early metastatic spread and poor delivery of effective treatments. Protein-based therapeutics represent an attractive alternative to small-molecule drugs due to their strong biological activity, target selectivity, and generally limited off-target effects. In this work, we investigated whether a HER3-directed fusion construct, HPK, can function as a carrier to transport three different protein payloads—GFP, Gelonin, and GJA1-20k—into HER3-positive tumor cells. By incorporating a simple tagging motif onto each cargo, we assessed HPK’s capacity to load the proteins, recognize HER3 on the tumor cell surface, and promote internal uptake. Our findings show that HPK engages HER3 with high specificity, mediates efficient entry into cancer cells, and delivers intact, functional protein therapeutics. In vivo studies using melanoma and triple-negative breast cancer (TNBC) models further demonstrate that HPK enables payload activity within tumors. Collectively, these results identify HPK as a promising vehicle for successful protein delivery and highlight its potential utility in treating HER3-expressing cancers.", "source_company": "Cedars Sinai Medical Center", "source_org_type": "医院", "row_number": 1156, "target_meta": "HER3", "MOA_meta": "其他"}, {"drug_name": "G3iA", "company": "University of New Mexico", "org_type": "大学", "target": "GLUT3", "modality": "inhibitor", "importance_level": "低", "total_score": 47.5, "institution_score": 35, "track_score": 65, "milestone_score": 45, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "G3iA为GLUT3选择性抑制剂，通过调控TEAD-VASP-Actin轴降低TNBC细胞力学特性及转移潜能。大学机构+preclinical机制研究阶段+糖代谢靶点在肿瘤中关注度中等，导致整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6034", "id": "T57M_5wBZznHJdnt_W7P", "source_drug_name": "G3iA", "title": "GLUT3 inhibition reduces metastatic potential of triple-negative breast cancer cells by modulating cell mechanics via the TEAD-VASP-Actin axis", "abstract_text": "Triple-negative breast cancer (TNBC) is an aggressive breast cancer subtype lacking hormone (estrogen and progesterone) receptors and human epidermal growth factor receptor 2 (HER2), limiting the development of targeted therapies and contributing to poor patient outcomes. Metastasis, a major contributor to TNBC mortality, is closely linked to cancer cell mechanics—such as deformability and contractility—yet the molecular signaling cues from the tumor microenvironment (TME) that regulate these mechanical properties remain poorly understood.\nThis study investigates the role of glucose metabolism, particularly the role of glucose transporter 3 (GLUT3), in modulating TNBC cell mechanics and metastatic behavior. GLUT3, which has the highest glucose affinity among GLUT isoforms, is upregulated in various cancers including TNBC and is associated with poor prognosis and metastasis in TNBC patients. We demonstrate that GLUT3 inhibition by a selective inhibitor G3iA reduces glucose uptake, glycolysis and ATP production by 30% in TNBC cells, leading to AMP-activated protein kinase (AMPK) activation and suppression of myosin activity. The decreased myosin activity reduces cell contractility and ultimately cell invasion. AMPK activation also increased YAP phosphorylation resulting decreased YAP target gene expressions.\nWe also identified VASP, an actin filament nucleator and polymerase, is a novel YAP-TEAD target gene that regulated by the glucose-AMPK signaling axis. Additionally, GLUT3 inhibition triggers the cAMP-Protein Kinase A (PKA) pathway, which impairs actin polymerization through vasodilator-stimulated phosphoprotein (VASP). The decreased F-actin levels correlates with reduced cell stiffness, which was measured by Atomic Force Microscope. Using pharmacological inhibitors that activate the AMPK signaling or the cAMP-PKA signaling pathways, we show that these altered cell mechanics—cell stiffness and contractility—diminishes cell motility in vitro. Furthermore, we confirmed our findings that GLUT3 null TNBC cells show reduced lung metastasis in vivo.\nIn summary, we delineate molecular pathways that translate extracellular glucose signaling into regulation of cell mechanics and motility via actin rearrangement. For the actin rearrangement, we discovered that regulation of VASP in transcriptional level and post-translational modification is critical. Our findings reveal a novel mechanistic link between glucose metabolism and cancer cell mechanics with detailed molecular mechanisms, offering a promising therapeutic avenue for mitigating TNBC metastasis.", "source_company": "University of New Mexico", "source_org_type": "大学", "row_number": 1180, "target_meta": "SLC2A3", "MOA_meta": "抑制剂"}, {"drug_name": "KS-20260", "company": "Yonsei University College of Medicine", "org_type": "大学", "target": "IRP2", "modality": "inhibitor", "importance_level": "低", "total_score": 47.5, "institution_score": 25, "track_score": 75, "milestone_score": 45, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "KS-20260为IRP2抑制剂，IRP2为结直肠癌中相对新颖的铁稳态调控靶点，但非当前主流热门靶点。机构为大学，处于preclinical阶段且仅初步体内实验，整体开发热度和里程碑价值有限。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5622", "id": "hJ7M_5wBZznHJdnt_W3O", "source_drug_name": "KS-20260", "title": "AI-driven discovery of an IRP2-EGFR dual-targeting strategy reveals synergistic antitumor efficacy in colorectal cancer", "abstract_text": "Background: IRP2 is a key regulator of intracellular iron homeostasis and is known to be overexpressed in colorectal cancer (CRC). As a relatively novel therapeutic target, IRP2 has been implicated in tumor progression, and our previous study demonstrated the antitumor effects of IRP2 inhibitors. To broaden the therapeutic potential of IRP2 inhibition and establish effective combination strategies, we applied a multifaceted AI-based predictive approach to identify compounds capable of synergizing with the IRP2 inhibitor.\nMethods: We predicted compounds capable of producing a synergistic effect with IRP2 inhibition using an AI-based model on the AIGEN InSight platform. Cell viability was assessed using CCK-8, and synergy scores were calculated using the SynergyFinder 3.0. To investigate the mechanism underlying the combination effect at the RNA level, we performed RNA sequencing (RNA-seq) and identified differentially expressed genes (DEGs) using the DESeq2 R package. Pathway enrichment analysis was conducted, and key findings were validated in CRC cell lines using qRT-PCR and western blotting.\nResults: Based on the AI-driven prediction model, Osimertinib was identified as a top-ranked candidate, achieving an AI-score of 0.73, which places it within the top 0.03% of all evaluated compounds. IRP2 inhibitor was subsequently optimized to generate KS-20260 with improved potency. The combination of KS-20260 and Osimertinib exhibited differential synergy scores across seven colorectal cancer cell lines. Notably, LoVo and DLD-1 cells showed the highest synergy scores of 10.845 and 7.843, respectively, and the combination treatment markedly reduced the protein levels of IRP2 and phosphorylated EGFR compared with single-agent treatments. Using RNA-seq data from LoVo cells treated with KS-20260, Osimertinib, or their combination, we analyzed pathways that were more affected by the combination treatment than the additive effect, defined as the average response of individual treatments. The Gene Set Enrichment Analysis (GSEA) revealed a significant downregulation of cell-cycle-related gene sets (e.g., CELL_CYCLE and CELL_CYCLE_PHASE_TRANSITION). Supporting these transcriptomic findings, the mRNA expression of key cell-cycle regulators, including CDK1, AURKB, CENPF, and E2F8, was decreased in the combination-treated cells. Furthermore, in the preliminary in vivo experiment, the combination-treated group (TGI 57.01%) exhibited a greater reduction in both tumor volume and tumor weight compared with the single-agent treatment groups (KS-20260, 38.37%; Osimertinib, 20.57%).\nConclusion: This study demonstrates that KS-20260 and Osimertinib combination therapy disrupts cell-cycle progression and enhances antitumor efficacy in colorectal cancer, supporting dual IRP2-EGFR targeting as a promising therapeutic strategy.", "source_company": "Yonsei University College of Medicine", "source_org_type": "大学", "row_number": 1235, "target_meta": "IREB2", "MOA_meta": "抑制剂"}, {"drug_name": "ROC-325", "company": "University of Arizona", "org_type": "大学", "target": "autophagy (lysosomal-mediated)", "modality": "inhibitor", "importance_level": "低", "total_score": 47, "institution_score": 30, "track_score": 65, "milestone_score": 60, "field_heat_score": 55, "bonus_score": 3, "brief_reason": "ROC-325为新型口服溶酶体自噬抑制剂，与CB-5339联合在RCC PDX模型中显示协同抗肿瘤作用。机构为大学非商业研发、赛道为自噬抑制（非最热门）、仍处preclinical阶段导致总体评分较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8843", "id": "xlXM_5wBX1NQZOEH-LS6", "source_drug_name": "ROC-325", "title": "p97/VCP inhibition with CB-5339 induces REDD1-dependent antitumor activity in renal cell carcinoma", "abstract_text": "Renal cell carcinoma (RCC) is the tenth most common cancer in the United States and disproportionately affects Hispanic and Native American populations, who experience higher incidence and mortality. Although current therapies targeting tyrosine kinases and immune checkpoints have extended survival, most patients ultimately develop resistance. This emphasizes the need for novel treatment strategies that disrupt essential survival pathways. The AAA+ ATPase p97/valosin-containing protein (VCP) is a central regulator of protein quality control that extracts misfolded or unfolded proteins from the endoplasmic reticulum (ER) for degradation, thereby preventing proteotoxic stress. We demonstrated that genetic knockdown of p97 significantly reduced RCC cell viability, supporting p97 as an essential survival factor and a promising therapeutic target. Consistent with this, the orally bioavailable, clinically relevant p97 inhibitor CB-5339 potently induced ER stress and apoptosis across human RCC cell lines and in Hispanic and Native American patient-derived xenograft (PDX) models. Transcriptomic profiling identified REDD1 as the most strongly upregulated gene following CB-5339 treatment. CRISPR-mediated knockout studies showed that REDD1 was required for maximal induction of ER stress and apoptosis, indicating that CB-5339 triggers a REDD1-dependent stress response. Because REDD1 is a negative regulator of mTORC1, we further assessed downstream effects on nutrient-sensing pathways. CB-5339 treatment inhibited mTORC1 activity and activated autophagy, as confirmed by autophagic flux assays using the lysosomal inhibitor bafilomycin-A1. Therefore, we hypothesized that combining p97 inhibition with autophagy blockade would enhance cytotoxicity by preventing the compensatory autophagic response. Consistent with this, co-treatment with CB-5339 and the lysosomal autophagy inhibitor ROC-325 produced strong synergy, significantly increasing apoptosis and reducing viability compared with either agent alone. In RCC xenograft models, the combination achieved marked tumor suppression, robust induction of apoptotic signaling, and excellent tolerability. Together, these results identify p97 as a novel therapeutic vulnerability in RCC and demonstrate that CB-5339’s anticancer effects are driven by REDD1-mediated ER stress and cell death. The synergistic efficacy of CB-5339 and ROC-325 highlights the therapeutic potential of combining proteostasis disruption with autophagy inhibition. Moreover, the use of multiple RCC PDX models enhances the translational relevance of this approach and provides a strong rationale for clinical investigation of p97 inhibition alone and in combination with autophagy-targeting agents in RCC.", "source_company": "University of Arizona", "source_org_type": "大学", "row_number": 80, "target_meta": "not available", "MOA_meta": "抑制剂"}, {"drug_name": "sPD1-TruncT1", "company": "The Hong Kong Polytechnic University", "org_type": "大学", "target": "TWIST1", "modality": "DNA vaccine", "importance_level": "低", "total_score": 47, "institution_score": 25, "track_score": 75, "milestone_score": 45, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "sPD1-TruncT1为基于sPD1的DNA疫苗，靶向表位优化的TWIST1抗原，旨在增强抗肿瘤T细胞免疫。大学机构分数较低、仍处preclinical优化阶段且未见突破性机制，整体重要性有限。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3654", "id": "AVXM_5wBX1NQZOEH-LG5", "source_drug_name": "sPD1-TruncT1", "title": "Enhanced cancer immunotherapy via sPD1-based DNA vaccination targeting epitope-focused TWIST1 antigen", "abstract_text": "TWIST1, a basic helix-loop-helix transcription factor, is overexpressed in a variety of tumors such as melanoma, breast, colon cancer and mesothelioma, and associated with tumorigenesis and metastasis. We have previously shown that full-length TWIST1 vaccine elicited cytotoxic T lymphocytes (CTLs) that recognized TWIST1-expressing tumors and conferred protection against tumor challenge in the form of DNA vaccine and adeno-associated viral vector system, highlighting TWIST1 as a promising target for cancer immunotherapy. In this study, we sought to apply optimization approach on the TWIST1-based vaccine platform in order to enhance T cell immunity and reduce potential toxicity.\nWe developed a novel soluble PD-1 (sPD1)-based DNA vaccine encoding a truncated version of TWIST1 (sPD1-TruncT1) that includes major T cell epitopes found in both human and mouse proteins. The immunogenicity and antitumor efficacy of the vaccine were evaluated and compared in parallel to full-length TWIST1 vaccine in two murine models of TWIST1-expressing tumors. By doing epitope mapping, we identified immunodominant T cell epitopes within the TWIST1 antigen, showing that majority of T cells recognized a C-terminal conserved region. sPD1-based DNA vaccine encoding epitopes of this conserved region, via in vivo electroporation (EP), elicited more robust TWIST1-specific T cell responses compared to full-length TWIST1 vaccine. Furthermore, these TWIST1-specific T cells were polyfunctional because they produced multiple effector cytokines when encountering TWIST1-expressing tumors. In addition, immunotherapy with the sPD1-TruncT1 vaccine showed a notable enhancement in antitumor efficacy in both preventive and therapeutic scenarios. With the widespread expression of TWIST1 in different cancer types, truncated TWIST1 vaccination has high potential for cancer immunotherapy and warrants investigation in human clinical trials to evaluate its applications as a vaccine for patients with WT1-expressing cancers.", "source_company": "The Hong Kong Polytechnic University", "source_org_type": "大学", "row_number": 310, "target_meta": "TWIST1", "MOA_meta": "DNA疫苗"}, {"drug_name": "Pixantrone-based PROTAC", "company": "Baylor College of Medicine", "org_type": "大学", "target": "KRAS", "modality": "PROTAC", "importance_level": "低", "total_score": 47, "institution_score": 35, "track_score": 90, "milestone_score": 25, "field_heat_score": 75, "bonus_score": 0, "brief_reason": "靶向KRAS的PROTAC，赛道热度高（KRAS+PROTAC双热门），但研发机构为大学非商业实体且当前化合物降解效果有限、无显著活性，整体开发早期且未见积极里程碑。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6466", "id": "IlXM_5wBX1NQZOEH-LG5", "source_drug_name": "Pixantrone-based PROTAC", "title": "Design and optimization of small-molecule PROTACs targeting KRAS", "abstract_text": "KRAS is one of the most frequently mutated oncogenes in cancer and is strongly associated with poor outcomes. For decades, it has been considered ‘undruggable’ because its surface lacks the deep binding pockets that small-molecule drugs can typically target and the very strong affinity to GTP/GDP makes it difficult for drugs to outcompete GTP. Recently, advances in structural biology led to the discovery of a regulatory allosteric pocket in the KRAS(G12D) mutant, which has opened the door to new therapeutic approaches for pancreatic cancer; unfortunately, single-agent allosteric inhibitors have shown little anti-cancer activity in patients. PROTACs (proteolysis-targeting chimeras) offer advantages over traditional inhibitors by degrading entire proteins independent of active sites or deep, hydrophobic binding pockets, making them attractive for hard-to-target proteins like KRAS.\nIn our lab, we carried out an in silico screen and identified Pixantrone as the top hit for a possible KRAS-binding warhead. Based on this, we synthesized a library of PROTACs with various lengths of alkyl linkers tethering Pixantrone, the warhead targeting KRAS, to Pomalidomide, a well-known E3 ligase recruiter. We then assessed our PROTACs’ effectiveness in degrading KRAS and the corresponding effects in pancreatic cancer cell lines. In addition, we evaluated the MAPK signaling cascade, one of the KRAS downstream pathways. Evaluation of the Pixantrone-based PROTACs showed limited KRAS degradation and no significant effects on MAPK signaling or cell death, as assessed by cell viability and immunoblotting assays. These findings suggest that Pixantrone is not a suitable warhead for KRAS targeting. Moving forward, we are shifting our efforts toward validating other candidates from the screen, since PROTAC efficacy may be independent of kinase inhibition efficacy of the warhead alone. If successful, an improved PROTAC design may overcome the clinical ineffectiveness of the current generation of allosteric inhibitors.", "source_company": "Baylor College of Medicine", "source_org_type": "大学", "row_number": 334, "target_meta": "KRAS", "MOA_meta": "PROTAC"}, {"drug_name": "TATE-Cy5", "company": "Sunnybrook Research Institute", "org_type": "研究机构", "target": "SSTR2", "modality": "fluorescent imaging agent", "importance_level": "低", "total_score": 47, "institution_score": 35, "track_score": 65, "milestone_score": 45, "field_heat_score": 55, "bonus_score": 3, "brief_reason": "TATE-Cy5为靶向SSTR2的Cy5荧光探针，用于检测NETs患者血液中CTCs，作为现有DOTATATE诊疗探针的液态活检伴随工具。研究机构背景+早期preclinical阶段+荧光CTC检测非主流热门赛道导致总体评分较低，但借力成熟SSTR2靶向体系有一定转化潜力。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10279", "id": "6FXM_5wBX1NQZOEH-LG6", "source_drug_name": "TATE-Cy5", "title": "Detection of circulating tumor cells (CTCs) as a next-generation liquid biopsy for neuroendocrine tumors (NETs) by taking advantage of existing theranostic probes", "abstract_text": "When neuroendocrine cells become cancerous, the resulting Neuroendocrine Tumours (NETs) can be challenging to detect. NETs are often asymptomatic, because they often lead to hormonal imbalances, which are associated with other diseases. In terms of biomarkers, NETs often overexpress Somatostatin Receptor 2 (SSTR2). This biomarker is the primary method of detecting and treating NETs and a specific molecule called DOTATATE is used for clinical PET scans and therapies to detect and combat this cancer in NET patients. DOTATATE compounds consist of two active components. The DOTA component is a metal chelator that carries the component detected by PET scan. The TATE component is a modified octreotate compound which binds to the Somatostatin Receptor 2 (SSTR2).Here, we offer the TATE-Cy5 probe, which takes advantage of the clinical use of DOTATATE for use in a blood test. Similar to DOTATATE, TATE-Cy5 also contains tyrosine-3-octreotate, meaning that it can to bind to SSTRs with equal effectiveness. However, instead of the DOTA chelator, TATE-Cy5 has a fluorescent Cy5 probe, which can be used to detect the presence of NETs because we hypothesize we can detect circulating tumor cells (CTCs) in patient blood samples. We predict that there are high numbers of CTCs that bind the TATE-Cy5 probe in patient whole blood samples according to disease severity.Results show that TATE-Cy5 binds to cell lines overexpressing SSTR2. Moving onto clinical samples, we also observe the presence of CTCs that bind TATE-Cy5 in whole blood samples from NET patients. We further subclassified CTCs as based on a combination of co-expressing biomarkers, CTCS that are positive for SSTR2, and tumours positive for both SSTR2 and EpCAM. With further testing, we will be able to use TATE-Cy5 to monitor patient treatment response over time.In summary, we have developed a novel and cancer specific CTC liquid biopsy that takes advantage of existing imaging probes in the form of DOTATATE. This technology has significant clinical implications because it can be used as a companion liquid biopsy for existing and emerging therapies.", "source_company": "Sunnybrook Research Institute", "source_org_type": "研究机构", "row_number": 471, "target_meta": "SSTR2", "MOA_meta": "荧光显像剂"}, {"drug_name": "WEE1 kinase inhibitors", "company": "Baruch S. Blumberg Institute", "org_type": "研究机构", "target": "WEE1", "modality": "inhibitor", "importance_level": "低", "total_score": 47, "institution_score": 30, "track_score": 80, "milestone_score": 40, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "WEE1激酶抑制剂针对WEE1靶点，在DACH1缺失的前列腺癌模型中显示增强敏感性，揭示潜在生物标志物指导用药，但该研究来自研究机构，处于基础前临床机制探索阶段，无特定药物推进至临床。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4657", "id": "_lXM_5wBX1NQZOEH-LG6", "source_drug_name": "WEE1 kinase inhibitors", "title": "Deletion of the DACH1 gene tumor suppressor increases replication fork stress, epithelial mesenchymal transition and sensitivity to WEE1 kinase inhibitors in prostate cancer", "abstract_text": "• Introduction: Patients with metastatic prostate cancer have poor survival with DNA damage repair pathway abnormalities. The cell fate determination factor DACH1 is deleted (shallow or deep deletion) in ~5-12% of PCa patients, but up to 65% of metastatic PCa. WEE1 kinase is one of the most upregulated kinases in the human prostate cancer kinome associated with metastatic progression in prostate cancer (mCRPC). We determined the potential for differential sensitivity of PCa to Wee1 Kinase inhibitors (WEE1Ki) based on DACH1 expression profiles.\n• Methods: Analysis of patient gene expression, tumor histology, organoids derived from prostate epithelial cell-specific DACH1 deletion prostate onco-mice, DNA replication fork assays, tissue culture.\n• Findings: DACH1 deficient (Dach1-/-) cells showed enhanced cell killing by WEE1Ki, that was reversed by reintroduction of DACH1a. Increased sensitivity to WEE1Ki was shown in fibroblasts, prostate cancer cell lines and in organoids derived from human prostate cancer cell lines or the prostate epithelium of Dach1 deletion onco-mice. DACH1 deletion dramatically enhanced non replicating S phase in the presence of WEE1Ki. Dach1-/- cells showed increased replication fork stress, that was reversed by reintroduction of the DACH1a isoform. DACH1 epithelial cell deletion onco-mice, and the prostate organoids derived therefrom, was associated with the induction of epithelial mesenchymal transition (EMT) with a corresponding increase in AKTSer473P, ATRThr1989p and CHK1 Ser345P. Increased sensitivity to WEE1Ki is associated with reduced SETD2 or NSD1/KMT3B expression, and reduced RRM2, a ribonucleotide reductase subunit, thereby inducing dNTP starvation. DACH1 expression was highly correlated with SETD2, NSD1 and RRM2. Gene ontology terms associated with DACH1 DNA binding templates included nucleoside metabolic processes. Like several other tumor suppressor genes (RB, FOXO3), DACH1 restrained dNTP production. dNTP production also requires NDPK (Nucleoside Diphosphate Kinase) encoded by NME genes. Consistent with the inhibition of dNTP production, DACH1a expression in prostate cancer PC3 cells reduced NME1 and NME7 (NDPKA expression), and DACH1 was strongly inversely correlated with NME1 in human prostate cancer (N=491. P 9.9e-24).\n• Conclusions: As DACH1 deletion PCa subclass conveys specific therapeutic sensitivities, that is dependent upon the DACH1a isoform, testing for DACH1a in patient samples may be warranted.", "source_company": "Baruch S. Blumberg Institute", "source_org_type": "研究机构", "row_number": 486, "target_meta": "WEE1", "MOA_meta": "抑制剂"}, {"drug_name": "SUV39H1 inhibitor", "company": "Sanford Burnham Prebys Med. Discovery Inst.", "org_type": "研究机构", "target": "SUV39H1", "modality": "inhibitor", "importance_level": "低", "total_score": 47, "institution_score": 35, "track_score": 75, "milestone_score": 30, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "靶向SUV39H1表观遗传调控以诱导病毒模拟并抑制胶质母细胞瘤生长，机制新颖但仅为研究机构preclinical概念性工作，摘要仍处于embargo状态无具体数据披露。打分偏低主要因机构非企业、开发阶段早期且信息严重不足。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11501", "id": "kFXM_5wBX1NQZOEH-LK6", "source_drug_name": "SUV39H1 inhibitor", "title": "Targeting suv39h1 epigenetic silencing to induce viral mimicry and suppress glioblastoma growth", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Sanford Burnham Prebys Med. Discovery Inst.", "source_org_type": "研究机构", "row_number": 578, "target_meta": "SUV39H1", "MOA_meta": "抑制剂"}, {"drug_name": "VEGF targeting TKIs", "company": "University of Texas Southwestern Medical Center", "org_type": "大学/医院", "target": "VEGF", "modality": "inhibitor", "importance_level": "低", "total_score": 47, "institution_score": 35, "track_score": 75, "milestone_score": 30, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "VEGF靶向TKI为ccRCC标准治疗药物，本摘要为学术机构的空间多组学研究，揭示IO后残余肿瘤中靶点变化而非新药开发。机构非企业、缺乏新药里程碑导致总体分值偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10079", "id": "9FXM_5wBX1NQZOEH-LK6", "source_drug_name": "VEGF targeting TKIs", "title": "Spatial multi-omics profiling of clear cell renal cell carcinoma (ccRCC) pre-and post-immunotherapy identifies new druggable targets", "abstract_text": "Introduction: Immunotherapy (IO) and VEGF targeting TKIs have transformed outcomes of patients with advanced ccRCC. However, much less is known about treatment resistance mechanisms after IO therapy.\nMethods: 15 patients (pts) with advanced ccRCC who had tumor samples pre- and post-treatment (Tx, IO-IO or IO-TKI) were included in this study. Tumors were profiled using the Nanostring GeoMx spatial profiling platform. 4 to 12 regions of interest (ROIs) were selected for each patient, and the ROIs were further segmented into tumor (PanCK+), immune (CD45+), and stroma (PanCk-, CD45-) compartments. Differentially expressed genes and proteins were assessed with Gene Set Enrichment Analysis (GSEA). Bulk gene expression was further deconvoluted to profile immune cell subsets using CIBERSORT. Deep learning algorithms analyzed H&E slides for angiogenic, immune gene signatures, and non-negative matrix factorization (NMF) clustering.\nResults: In the tumor compartment (PanCK+), several clinically druggable targets such as Axl, HER2, TROP-2, GITR, HIF-1α, and FGFR2 were significantly upregulated after IO. Interestingly, Trop-2 expression was upregulated in IO-IO (Log2FC 0.038, p<0.01) post-Tx but not after IO-TKI (Log2FC -0.070, p<0.01). Some patients who received IO/TKIs had decreased tumor angiogenic expression post-Tx. NMF clustering classified post-Tx as NMF4 in 6/15 patients (4 of 10 in IO-TKI cohort and 2 of 5 in IO-IO cohort). NMF cluster 3 remained post-IO in most patients.While most pre-IO samples had moderate to high immune infiltration, post-IO samples had even higher levels. Notably, CIBERSORT profiling revealed post-IO proportion of immune suppressive regulatory T cells were decreased (IO-TKI, p <0.01), while cytotoxic CD8+ T cells were increased (IO-TKI, p <0.01) with both Tx cohorts. However, resting NK cells were increased (p=0.29), while activated NK cells were decreased (p <0.01) significantly only in IO-IO treated subsets.\nConclusion: Molecular gene expression changes in RCC after IO-based therapy identified clinical targets in residual tumors. NMF cluster 4 persistence, CD8+ infiltration, and reduction in Treg proportion suggests an expansion or persistence of immune cells post-IO. NMF cluster 3 and increased proportion of resting NK cells may explain the resistance of residual tumor post-IO. Given the heterogeneity in RCC, it is imperative to profile individual tumors to improve IO therapy outcomes. Ongoing analyses include IHC target validation.", "source_company": "University of Texas Southwestern Medical Center\nUT Southwestern Medical Center", "source_org_type": "医院\n大学", "row_number": 645, "target_meta": "VEGF family", "MOA_meta": "抑制剂"}, {"drug_name": "FAK inhibitor", "company": "University of California, San Diego", "org_type": "大学", "target": "FAK", "modality": "inhibitor", "importance_level": "低", "total_score": 47, "institution_score": 35, "track_score": 65, "milestone_score": 45, "field_heat_score": 60, "bonus_score": 2, "brief_reason": "靶向FAK的激酶抑制剂可特异性上调卵巢癌细胞MHC-II表达，促进抗肿瘤免疫；大学机构非商业开发、仅机制研究+动物模型、无临床阶段导致总体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1408", "id": "aJ7ECZ0BZznHJdntvNYd", "source_drug_name": "FAK inhibitor", "title": "Opposing control of MHC-II antigen presentation by FAK and PYK2: Implications for therapeutic intervention", "abstract_text": "High-grade serous ovarian cancer (HGSOC) is the most lethal gynecologic malignancy in the U.S. and is marked by resistance to chemo- and immunotherapy. Although focal adhesion kinases (FAK and PYK2) are known to induce tumor microenvironment immunosuppression, their role in altering tumor-cell major histocompatibility complex class-II (MHC-II) presentation requires further investigation. HGSOC tumors have few mutations but frequently show FAK amplification (~75%). Notably, elevated MHC-II expression correlates with longer progression-free survival in recurrent HGSOC, likely through enhanced CD4⁺ T-cell activation and improved anti-tumor immunity. Flow cytometry analysis revealed that ATP competitive small molecule inhibition of FAK kinase activity (FAKi) increases MHC-II antigen presentation in vitro and in vivo. Targeted FAK protein degradation following treatment with a FAK proteolysis targeting chimera (FAK-PROTAC) produced a similar effect. In a syngeneic orthotopic mouse model, FAK depletion induced MHC-II to levels comparable to kinase-dead FAK, consistent with the loss of FAK activity in promoting tumor MHC-II expression. As ovarian tumor cells also express the FAK-related homolog PYK2, CRISPR was employed to selectively inactivate FAK and or PYK2 expression in human OVCAR3, murine KMF, and murine HGS2 ovarian tumor models. Notably, loss of FAK, but not PYK2, resulted in enhanced MHC-II presentation in these cells. As tumor cell treatment with a dual FAK-PYK2 inhibitor or PROTAC that targets FAK and PYK2 does not induce MHC-II expression as does selective loss of FAK, our results support a distinct immunogenic role for PYK2 in ovarian tumor cells. Ongoing studies are evaluating PYK2 mechanism of action upon FAK inhibition and the regulation of CIITA (class II, major histocompatibility complex, transactivator) transcription. Collectively, our findings suggest roles for FAK-specific inhibitors that may potentiate MHC-II-related adaptive immune responses as a therapeutic strategy for advanced ovarian cancer.", "source_company": "University of California, San Diego", "source_org_type": "大学", "row_number": 811, "target_meta": "FAK", "MOA_meta": "抑制剂"}, {"drug_name": "MHP1", "company": "Columbia University Vagelos College of Physicians & Surgeons", "org_type": "大学", "target": "未披露", "modality": "peptide", "importance_level": "低", "total_score": 47, "institution_score": 35, "track_score": 65, "milestone_score": 45, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "MHP1为转移性前列腺癌 homing peptide，可实现肿瘤特异性靶向递送，但靶点/受体尚未明确披露，仅初步鉴定候选蛋白。大学机构+早期体外体内验证阶段，赛道为peptide靶向递送有一定潜力但非最热门，无显著里程碑进展。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5563", "id": "eVXM_5wBX1NQZOEH-LS6", "source_drug_name": "MHP1", "title": "A peptide-based drug delivery system to target metastatic prostate cancer", "abstract_text": "While effective treatments for prostate cancer (PC) such as androgen deprivation therapy (ADT) have been developed, it is still a challenge to treat advanced PC, which has become resistant to ADT or has metastasized. Lately, therapeutic agents that selectively target PCs such as [177Lu]Lu-PSMA-617 have shown promise, suggesting that tumor-specific drug delivery may greatly improve the management of metastatic castration-resistant PC. Here, we report a novel peptide, MHP1 (metastasis homing peptide 1), which effectively homes to metastatic PC in vivo.MHP1 was identified by phage display using experimental metastasis mouse models using the androgen-independent PC-3 human cancer cell line. The mouse models were prepared by either directly injecting the cells into the tibia and/or the brain or through intracardiac or intravenous injections to produce disseminated tumors. Phage display was performed using a cyclic CX7C peptide library expressed on T7 phage. To enrich for peptides that effectively home to metastatic PCs, the phage display was performed in mice by first performing 1 round of ex vivo phage panning using cell suspensions prepared from PC-3 tibia xenografts, followed by 3-4 rounds of in vivo selections in disseminated metastasis mice. DNA sequencing of the enriched phage clones yielded 150 candidate peptides. Phage clones that expressed each peptide on the coat protein were then mixed at an equimolar ratio to produce champion phage pools. “Play-off” in vivo phage display studies were performed by systemically injecting the phage pools into disseminated PC-3 tumor mice. A phage clone that expressed the MHP1 peptide showed the highest tumor-specificity by homing to tumors in various organs without accumulating into corresponding normal tissues. The MHP1 peptide chemically synthesized with a fluorescent tag (FAM-MHP1) effectively homed to tibia and brain xenograft PC-3 tumors. It also homed to disseminated metastatic PC-3 tumors in various organs, such as the jaw, femur, lymph nodes, and eye. Of note, in a spontaneous metastasis model prepared with 22Rv1 human PC cells, FAM-MHP1 homed more effectively to metastatic tumors than to the primary tumor. To identify the receptor of MHP1, affinity chromatography was performed by passing tissue lysates of PC-3 tibia tumors over MHP1-coated beads. A protein was eluted with the MHP1 peptide (but not by a control peptide). Mass spectrometry analysis revealed a list of candidate proteins. Preliminary data suggest that one of the candidates appears promising for being highly expressed in PC tissues. Interestingly, while the protein is intracellular in normal cells, it is misplaced onto the surface of some PC cells making it available for affinity-based targeting. These results suggest that the MHP1 peptide may serve as a promising platform to target metastatic PC. Characterization of the receptor may also lead to additional PC-specific therapies and deeper understanding of PC biology.", "source_company": "Columbia University Vagelos College of Physicians & Surgeons", "source_org_type": "大学", "row_number": 916, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "novel peptide decoy targeting mitochondrial dihydrolipoyl transacetylase-driven redox signaling", "company": "Emory Winship Cancer Institute", "org_type": "研究机构", "target": "mitochondrial dihydrolipoyl transacetylase (DLAT)", "modality": "peptide decoy", "importance_level": "低", "total_score": 47, "institution_score": 35, "track_score": 65, "milestone_score": 45, "field_heat_score": 50, "bonus_score": 3, "brief_reason": "药物为靶向线粒体DLAT驱动的氧化还原信号的novel peptide decoy，可改善化疗效果，机制新颖但靶点非热门。机构为大学附属癌症研究所非商业公司、赛道为peptide-based新机制但非主流热门modality、摘要embargoed仅体现preclinical概念阶段故总分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11435", "id": "jlXM_5wBX1NQZOEH-LS6", "source_drug_name": "novel peptide decoy targeting mitochondrial dihydrolipoyl transacetylase-driven redox signaling", "title": "Novel peptide decoy targeting mitochondrial dihydrolipoyl transacetylase-driven redox signaling to improve cancer chemotherapy outcomes", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Emory Winship Cancer Institute", "source_org_type": "研究机构", "row_number": 934, "target_meta": "DLAT", "MOA_meta": "其他"}, {"drug_name": "A2-MMAE", "company": "UCLA David Geffen School of Medicine", "org_type": "大学", "target": "PSCA", "modality": "ADC", "importance_level": "低", "total_score": 47, "institution_score": 30, "track_score": 70, "milestone_score": 50, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "药物为针对PSCA的ADC，PSCA在晚期前列腺癌中高表达且正常组织低表达，ADC赛道热门但PSCA靶点非顶级热门。机构为大学非商业公司，处于preclinical体外+稳定性研究阶段，无体内疗效数据，整体开发早期。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5484", "id": "t1XM_5wBX1NQZOEH-LS6", "source_drug_name": "A2-MMAE", "title": "Development of a novel PSCA-targeting antibody-drug conjugate with high potency and stability for prostate cancer therapy", "abstract_text": "Antibody-drug conjugates (ADCs) enable the selective delivery of highly cytotoxic payloads to tumors and are emerging as new, promising therapeutic options for prostate cancer. Prostate stem cell antigen (PSCA) is a cell-surface antigen that is highly overexpressed in prostate cancer and upregulated in advanced disease states, while minimally expressed in normal tissues, making it an ideal target for ADC therapy. In this study, we identified and generated full-length human anti-PSCA antibodies, exhibiting high binding affinity and rapid internalization into PSCA-expressing cancer cells. Various cytotoxic drugs (e.g., monomethyl auristatin E (MMAE), DM1, etc.) were conjugated to the lead anti-human PSCA antibody (A2) using a chemically validated linker. Among the resulting ADC candidates, A2-MMAE demonstrated the most potent, concentration-dependent cytotoxicity against PSCA-positive human prostate cancer cell lines, with an IC₅₀ range of 0.18-2.17 nM, while exhibiting no cytotoxicity in PSCA-negative cells. Hydrophobic interaction chromatography (HIC-HPLC) analysis revealed a heterogeneous distribution of drug-to-antibody ratios (DARs), with an average DAR of 4.84. Furthermore, A2-MMAE retained a high level of total ADC integrity following 10 days of incubation in mouse plasma, indicating a robust plasma stability. These findings suggest that the novel anti-PSCA ADC (anti-PSCA-VC-PAB-MMAE), characterized by its strong target specificity, high potency, and excellent stability, holds promise as a safer and more effective therapeutic for prostate cancer. Ongoing studies will evaluate its in vivo antitumor efficacy, tolerability, safety, and pharmacokinetic/pharmacodynamic (PK/PD) profiling in mouse models.", "source_company": "UCLA David Geffen School of Medicine", "source_org_type": "大学", "row_number": 966, "target_meta": "PSCA", "MOA_meta": "抗体偶联药物"}, {"drug_name": "Nanobody adaptor-directed CAR T cells", "company": "Houston Methodist Research Institute", "org_type": "研究机构", "target": "未披露", "modality": "CAR", "importance_level": "低", "total_score": 47, "institution_score": 35, "track_score": 85, "milestone_score": 30, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "采用nanobody适配器定向的CAR-T细胞技术针对实体瘤实现精准安全靶向，但摘要被embargo未披露具体靶点和数据。机构为研究型而非头部药企、仅preclinical阶段无明确里程碑导致总分较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11518", "id": "rp3ECZ0B4z9FlvORyiZD", "source_drug_name": "Nanobody adaptor-directed CAR T cells", "title": "Nanobody adaptor-directed CAR T cells enable precise and safe targeting of solid tumors", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Houston Methodist Research Institute", "source_org_type": "研究机构", "row_number": 1099, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "EGFR tyrosine kinase inhibitors", "company": "Mass General Brigham Cancer Institute", "org_type": "医院", "target": "EGFR", "modality": "inhibitor", "importance_level": "低", "total_score": 47, "institution_score": 35, "track_score": 80, "milestone_score": 30, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "药品为EGFR TKI，靶点EGFR在NSCLC领域成熟且热门，但研究机构为医院而非药企公司，摘要仅为机制探索无药物开发里程碑。总分偏低主要因机构类型和开发阶段限制。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/2413", "id": "BZ7M_5wBZznHJdnt_W7O", "source_drug_name": "EGFR tyrosine kinase inhibitors", "title": "Activation of HIF1ɑ drives oxidative stress and promotes deep senescence inEGFR-mutant NSCLC drug tolerant persister cells", "abstract_text": "Non-small cell lung cancers with oncogenic mutations in EGFR (exon 19 deletions or L858R substitutions) are sensitive to EGFR tyrosine kinase inhibitors (TKIs), which induce deep and durable responses in the majority of patients. However, despite these responses, the development of acquired resistance to EGFR TKIs is inevitable. Preclinical studies have implicated a role for drug-tolerant persister (DTP) cells in the development of acquired drug resistance. DTPs are a subpopulation of cancer cells that survive initial TKI therapy by entering a reversible, slow-cycling or quiescent state. Mechanistically, DTPs leverage reversible, non-genomic mechanisms, including epigenetic plasticity, activation of survival signaling pathways, and lineage switching, to maintain a drug-tolerant state. Importantly, DTP cells can undergo further evolution and acquire mechanisms of drug resistance that drive disease relapse. To identify vulnerabilities of DTP cells, we characterized DTP cells in patient-derived xenograft models of EGFR-mutant NSCLC and malignant pleural effusions from patients treated with EGFR TKIs. We observed that HIF1-ɑ (hypoxia-inducible factor 1 alpha) signaling was consistently downregulated in DTP cells across models and patients. Unexpectedly, stabilization and reactivation of HIF-1α with the prolyl hydroxylase inhibitor, resensitized DTP cells to EGFR TKIs and suppressed the emergence of drug-resistant clones. Mechanistically, HIF-1 ɑreactivation increases oxidative stress in DTPs and promotes entry to an irreversible deep senescence state. These results add to a growing body of evidence that mitigation of oxidative stress is critical for DTP survival and suggest that reactivation of HIF-1α signaling may provide a therapeutic strategy to prevent emergence of resistance in EGFR-mutant NSCLC.", "source_company": "Mass General Brigham Cancer Institute", "source_org_type": "医院", "row_number": 1134, "target_meta": "EGFR", "MOA_meta": "抑制剂"}, {"drug_name": "brigatinib-based degrader", "company": "Louisiana State University Health Sciences Center", "org_type": "大学", "target": "Focal Adhesion Kinase", "modality": "PROTAC", "importance_level": "低", "total_score": 47, "institution_score": 25, "track_score": 85, "milestone_score": 40, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "基于brigatinib改造的PROTAC降解剂靶向Focal Adhesion Kinase (FAK)，在TNBC细胞系中实现选择性纳米摩尔级抑制和降解。机构为大学非商业实体得分较低，PROTAC赛道和TNBC未满足需求有一定热度，但仅体外preclinical初步结果，整体开发阶段早期导致总分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8711", "id": "F57M_5wBZznHJdnt_W7O", "source_drug_name": "brigatinib-based degrader", "title": "Brigatinib based degraders as a therapeutic strategy for triple negative breast cancer", "abstract_text": "Background: Treatment of patients with triple‐negative breast cancer (TNBC) has been challenging due to the absence of well‐defined molecular targets and high invasive and proliferative capabilities of these cells. Therefore, new therapeutic strategies for treatment of TNBC are urgently needed. Protease-targeted chimeras (PROTACs) are a class of emerging therapeutic inhibitors that recruit the ubiquitin E3 ligase to selectively degrade proteins. PROTAC degrader technology has shown robust results in inhibiting TNBC progression.\nMethods: RNA sequencing and analysis were done. Samples were submitted to PamGene for kinome profiling and analysis. Western blotting was performed to visualize protein expression. MTT assays were carried out to evaluate cell viability. Colony formation assays assessed changes in clonogenicity. Data were analyzed using Graph Pad Prism Software 8 using one-way ANOVA and the unpaired two-tailed Students t-test. All data were evaluated in triplicate against control cells.\nResults: Analysis of RNA sequencing in LM2-4175 TNBC cells treated with our target degrader showed increased genes associated with apoptosis and a decrease in genes associated with cell cycle checkpoint, DNA replication, and regulation of P53 signal transduction pathways. Kinase activity profiling of MDAMB231-LM2-4175 TNBC cells treated with our degrader showed a significant reduction in serine/threonine kinases (STKs) associated with Mitogen-activated protein kinase (MAPK) and cyclin-dependent kinase (CDK) families. In addition, we noticed a significant decrease in protein tyrosine kinases (PTK) associated with ephrin receptor proteins. Western blot analysis confirmed targeted degradation of Focal Adhesion Kinase in multiple TNBC cell lines (MDAMB-231-LM2-4175, MDAMB-468, and 4QXTB). MTT analysis of cell proliferation showed our degrader selectively targeted\nMDAMB231, MDAMB231-LM2-4175, MDAMB-468, and 4QXTB (Primary)TNBC cells over our non-neoplastic cell line, MCF10A, in a nanomolar range. Colony formation assays also showed our degrader was able to reduce clonogenicity in TNBC cell lines MDAMB231-LM2-4175, MDAMB-468, and 4QXTB.\nConclusions:Breast cancer is a diverse and intricate disease which is known to have unique inter- and intra-tumoral characteristics. We have identified a candidate PROTAC which can selectively target TNBC cells while minimally affecting normal bystander cells at nanomolar ranges in vitro. The further development of this degrader can serve as the fundamental basis for a novel therapeutic treatment in TNBC.", "source_company": "Louisiana State University Health Sciences Center", "source_org_type": "大学", "row_number": 1143, "target_meta": "FAK", "MOA_meta": "PROTAC"}, {"drug_name": "novel innate immune therapeutics", "company": "University of California, San Diego", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 46.5, "institution_score": 35, "track_score": 65, "milestone_score": 40, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "药物为新型先天免疫治疗剂，具体靶点和机制未在摘要中明确披露，仅在肾细胞癌ex vivo模型中显示功能影响。大学机构+早期探索性研究导致整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10559", "id": "eFXM_5wBX1NQZOEH-LK6", "source_drug_name": "novel innate immune therapeutics", "title": "Biomarker discovery and the targeting of tumor immune suppression in Renal Cell Carcinoma", "abstract_text": "Metastatic renal cell carcinoma (RCC) remains highly lethal despite advances in immunotherapy, highlighting the need for improved diagnostic biomarkers and therapeutic strategies that overcome immune suppression and identify patients most likely to benefit from specific treatments. RCC tumors contain high levels of pro-angiogenic, immune-suppressive macrophages that contribute to therapeutic resistance and correlate with poor survival. To address the hypothesis that circulating and tumor-derived biomarkers can inform personalized therapeutic strategies, we prospectively collected 26 fresh surgical RCC tumors with matched peripheral blood, along with peripheral blood from 20 healthy donors. We isolated serum and peripheral blood mononuclear cells (PBMCs) from normal and RCC patients for comprehensive profiling. Serum was analyzed by Olink and Illumina high-throughput proteomics to detect more than 5,000 and 9,000 serum proteins, respectively. PBMCs were analyzed by 25-color flow-based immunophenotyping and by single-cell RNA sequencing. Tumor specimens also analyzed by single-cell RNA sequencing and immunocytochemistry. To identify novel strategies to treat RCC, we established ex vivo tumor slice cultures of early stage RCC specimens and tested the impact of novel innate immune therapeutics on myeloid and T cell content and state, as well as on tumor and immune cell survival. Combined, these approaches enabled the identification of biomarkers of disease progression and immune response in RCC patients. By integrating serum proteomics, single-cell profiling and functional ex vivo tumor modeling as well as the impact of new therapeutic strategies, these results may inform biomarker-guided therapeutic strategies and may identify novel therapeutic strategies that can enhance durable responses and improve clinical outcomes for patients with RCC.", "source_company": "University of California, San Diego", "source_org_type": "大学", "row_number": 39, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "anti-PD1", "company": "University of California, San Francisco", "org_type": "大学", "target": "PD-1", "modality": "inhibitor", "importance_level": "低", "total_score": 46.5, "institution_score": 35, "track_score": 75, "milestone_score": 30, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "anti-PD1为经典PD-1抑制剂，靶点成熟且临床广泛验证，但本摘要仅为大学基础研究模型中抗性机制探索，无新药或特定候选物开发。机构为学术单位且处于preclinical机制研究阶段，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4912", "id": "hZ7M_5wBZznHJdnt_W7P", "source_drug_name": "anti-PD1", "title": "Characterization of high plasticity cell states in cutaneous squamous cell carcinoma in response to chemotherapy and immune checkpoint inhibitor treatments", "abstract_text": "Therapeutic resistance and cancer recurrence in cutaneous squamous cell carcinoma (cSCC) are strongly driven by genetic heterogeneity and phenotypic plasticity. Tumor cells that enter high-plasticity, low-proliferative states often evade cytotoxic therapies, including mitotic-targeting chemotherapeutics, yet the molecular mechanisms enabling these transitions and maintaining these states under therapeutic pressure remain poorly defined. Here, we seek to identify, characterize, and ultimately destabilize these therapy-refractory cell states across multiple treatment modalities.\nWe developed a chemically induced cSCC model in FVB mice using a single initiating dose of DMBA followed by 20 weeks of biweekly TPA promotion. Once tumors reached approximately one cubic centimeter, cohorts were assigned to distinct therapeutic regimens, including anti-PD1 immune checkpoint blockade, cisplatin, paclitaxel, and combination strategies incorporating the Pp2a inhibitor LB100 to test whether pharmacologic perturbation can drive mitotically silent tumor cells back into a proliferative, therapy-responsive state.\nNormal skin, papillomas, lymph nodes, and carcinomas were collected and approximately 900,000 cells were profiled using the 10x Genomics single-cell RNA-sequencing platform to map the full spectrum of malignant, stromal, and immune programs across various treatment groups. Ongoing analysis aims to resolve transcriptional signatures associated with high-plasticity states, identify treatment-induced and treatment-specific state transitions, and define potential therapy-evading intermediates that arise under drug pressure. A major focus is the discovery of metagene signatures that correlate with high-plasticity phenotypes and the evaluation of whether these molecular programs can be modulated or therapeutically targeted to re-sensitize tumors to conventional or immune-based therapies. In parallel, we are also examining how immune cell abundance, activation states, and lineage-specific gene expression profiles shift across treatment arms, particularly in response to anti-PD1 therapy, to uncover how the tumor immune microenvironment contributes to or counteracts the emergence of resistant high-plasticity cell states.\nThis work seeks to establish a unified mechanistic framework describing how plasticity-driven resistance emerges in cSCC and to identify points of therapeutic vulnerability that may improve responses to chemotherapy and immunotherapy both within and beyond this disease context.", "source_company": "University of California, San Francisco", "source_org_type": "大学", "row_number": 102, "target_meta": "PD1", "MOA_meta": "抑制剂"}, {"drug_name": "cyclic peptide radiopharmaceutical ligands", "company": "Stanford University", "org_type": "大学", "target": "未披露", "modality": "RLT imaging agent", "importance_level": "低", "total_score": 46.5, "institution_score": 40, "track_score": 75, "milestone_score": 30, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "药品为斯坦福大学开发的环肽放射性药物配体，靶点和具体机制未在摘要中披露，仅为方法学开发阶段。机构为大学非商业实体得低分，赛道为放射性配体领域有一定热度但开发早期导致总分较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11321", "id": "KZ7ECZ0BZznHJdntvNYd", "source_drug_name": "cyclic peptide radiopharmaceutical ligands", "title": "Integrated computational design and cDNA display selection enable cyclic peptide radiopharmaceutical ligand discovery", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Stanford University", "source_org_type": "大学", "row_number": 304, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "Cowpea Mosaic Virus", "company": "UC San Diego", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 46.5, "institution_score": 35, "track_score": 65, "milestone_score": 45, "field_heat_score": 55, "bonus_score": 3, "brief_reason": "Cowpea Mosaic Virus (CPMV) 作为植物病毒免疫调节剂，通过逆转免疫抑制性肿瘤微环境激发抗肿瘤免疫，与IL-12联用在小鼠卵巢癌模型显示协同效应。大学机构+早期动物模型研究+非主流热门modality导致总体分值偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9430", "id": "QVXM_5wBX1NQZOEH-LG5", "source_drug_name": "Cowpea Mosaic Virus", "title": "Synergistic therapy by combination of a plant virus immunomodulator and IL-12 against murine ovarian cancer", "abstract_text": "Cowpea Mosaic Virus (CPMV) is an immunostimulatory agent that can induce antitumor immunity by reversing the immunosuppressive tumor microenvironment (TME) upon intratumoral treatment. In situ injection of CPMV activates and recruits innate immune cells which initiate tumor cell killing and antigen processing, ultimately launching systemic and adaptive antitumoral immunity. IL-12 is a promising proinflammatory cytokine that facilitates antigen processing and promotes T cell proliferation. CPMV primarily activates innate immune cells while IL-12 plays a key role in the adaptive immune response; therefore, we hypothesized that the synergistic combination of CPMV and IL-12 would be beneficial for reducing tumor burden. We tested our study using a murine ovarian carcinoma model. Mice were inoculated with bioluminescent tumor cells. Tumor burden was monitored using bioluminescence, body weight, and circumference. Survival was established based on humane endpoints. Our data show that the combination of CPMV + IL-12 outperforms the single-arm treatment. Robust efficacy is demonstrated for the combination group. In ongoing studies, we are deciphering the mechanism of action through immunological investigation. This work was funded in part through grants from NIH: R01 CA224505 and R01 CA274640.", "source_company": "UC San Diego", "source_org_type": "大学", "row_number": 354, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "anti-GARP", "company": "Institut d’Investigacions Biomèdiques August Pi i Sunyer", "org_type": "研究机构", "target": "GARP", "modality": "inhibitor", "importance_level": "低", "total_score": 46.5, "institution_score": 30, "track_score": 75, "milestone_score": 40, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "anti-GARP抗体靶向GARP以阻断Treg细胞介导的TGF-β激活，逆转免疫抑制，在抗PD-L1+抗VEGFA耐药的MASH-HCC小鼠模型中延长生存。机构为学术研究机构且摘要被禁运，仅显示preclinical阶段证据，缺乏临床进展或重大里程碑。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11533", "id": "jfTW_5wBLOutsWDvgbHs", "source_drug_name": "anti-GARP", "title": "Anti-GARP reverts immune suppression and extends overall survival in a MASH-HCC murine model resistant to anti-PDL1+anti-VEGFA therapy", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Institut d’Investigacions Biomèdiques August Pi i Sunyer", "source_org_type": "研究机构", "row_number": 370, "target_meta": "CNGB1,GARP", "MOA_meta": "抑制剂"}, {"drug_name": "anti-GARP", "company": "Hospital Clínic", "org_type": "医院", "target": "GARP", "modality": "inhibitor", "importance_level": "低", "total_score": 46.5, "institution_score": 30, "track_score": 75, "milestone_score": 40, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "anti-GARP为靶向GARP的抗体药物，GARP为Treg表面蛋白介导TGF-β激活从而促进免疫抑制，在MASH-HCC模型中显示逆转免疫抑制并延长生存，但靶点非极热门。机构为医院而非药企导致institution_score低，摘要embargoed仅体现preclinical阶段且针对抗PD-L1+抗VEGFA耐药模型有活性，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11533", "id": "jfTW_5wBLOutsWDvgbHs", "source_drug_name": "anti-GARP", "title": "Anti-GARP reverts immune suppression and extends overall survival in a MASH-HCC murine model resistant to anti-PDL1+anti-VEGFA therapy", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Hospital Clínic", "source_org_type": "医院", "row_number": 371, "target_meta": "CNGB1,GARP", "MOA_meta": "抑制剂"}, {"drug_name": "mTOR inhibitors", "company": "University of California, San Diego", "org_type": "大学", "target": "mTOR", "modality": "inhibitor", "importance_level": "低", "total_score": 46.5, "institution_score": 35, "track_score": 65, "milestone_score": 40, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "mTOR抑制剂针对HNSCC中常见的PI3K/mTOR通路激活，但机制研究揭示AKT反馈导致EGFR-MAPK代偿激活引起耐药，建议联合EGFR靶向。机构为大学、仅机制探索无临床推进，赛道mTOR抑制在实体瘤非前沿热点导致总分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1842", "id": "iFXM_5wBX1NQZOEH-LG6", "source_drug_name": "mTOR inhibitors", "title": "mTOR inhibition activates the EGFR-MAPK network by a novel AKT-initiated feedback loop promoting adaptive resistance", "abstract_text": "Head and neck squamous cell carcinoma (HNSCC) is the sixth most common cancer globally, resulting in more than 300,000 deaths each year worldwide. Treatment options for HNSCC patients include surgery, radiation, chemotherapy, and molecularly targeted therapies, and although immunotherapies have recently revolutionized the treatment landscape, <20% of HNSCC patients respond to immune checkpoint blockade (ICB) therapies. The survival rate of HNSCC patients has changed only modestly over the past decades, and therefore, HNSCC is a significant global health problem with high mortality and morbidity. Genomic alterations converging on persistent activation of the PI3K/mTOR pathway (>80% of cases) represent one of the most frequently altered signaling circuits in HNSCC. This overreliance on PI3K/mTOR signaling for tumor growth may expose a cancer vulnerability that can be therapeutically exploited, as revealed by recent clinical trials of mTOR inhibitors (mTORi) in HNSCC in the adjuvant and neoadjuvant settings. However, mTORi are ineffective in patients with advanced HNSCC, highlighting the urgency of elucidating the mechanisms underlying mTORi resistance. By combining the power of systems biology and computational approaches, including a high-throughput kinase activity mapping strategy, CRISPR/Cas9 synthetic lethal screening, CRISPR-guided GFP-tagging of endogenous EGFR, and the analysis of the spatiotemporal activation of intracellular ERK pools, we have now identified the activation of EGFR-MAPK signaling induced by mTORi in HNSCC as a major adaptive compensatory resistance pathway. Mechanistically, we found that mTOR inhibition activates the EGFR-MAPK pathway by disrupting a novel AKT-regulated feedback loop that inactivates EGFR. Ultimately, our findings suggest that the adaptive activation of EGFR represents a new mechanism of mTORi resistance, and that EGFR co-targeting may be a potent therapeutic option for HNSCC. These findings may be relevant to a large number of cancer types that depend on PI3K/mTOR signaling but fail to respond to mTORi therapies as single agents.", "source_company": "University of California, San Diego", "source_org_type": "大学", "row_number": 401, "target_meta": "mTOR", "MOA_meta": "抑制剂"}, {"drug_name": "anti-PD1", "company": "Columbia University", "org_type": "大学", "target": "PD-1", "modality": "inhibitor", "importance_level": "低", "total_score": 46.5, "institution_score": 25, "track_score": 80, "milestone_score": 35, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "anti-PD1为经典PD-1抑制剂，本身机制成熟但非新型药物；由大学机构开展的机制研究，preclinical组合探索阶段，缺乏药物开发里程碑，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3290", "id": "sFXM_5wBX1NQZOEH-LG6", "source_drug_name": "anti-PD1", "title": "Targeting master regulators to reprogram neutrophils and enhance PD-1 blockade efficacy in castration-resistant prostate cancer", "abstract_text": "Introduction: Neutrophil-mediated immunosuppression limits immunotherapy in Castration-Resistant Prostate Cancer (CRPC), but its mechanisms are unclear. This study aims to identify the drivers of this immunosuppression and evaluate whether targeting Master Regulator (MR) proteins can reprogram neutrophils, remodel the tumor microenvironment (TME), and enhance PD-1 blockade efficacy.\nMethods: We used orthotopic CRPC models treated with MR inhibitors and anti-PD-1 therapy to assess neutrophil depletion and immune remodeling. Spatial profiling with the 5,000-plex Xenium panel along with cell types annotation via a curated scRNA-seq atlas, revealed a detailed map of tissue organization. Treatment effects on immune populations and spatial reorganization, particularly neutrophils, were quantified. VIPER-based analysis defined MR-driven neutrophil functional states, and spatial mapping was conducted using Xenium data. Finally, ligand-receptor interactions between neutrophils and tumor cells were explored through cell-cell communication network analysis.\nSummary of unpublished data: We conducted a pilot Xenium study across four treatment arms (vehicle, Trametinib, anti-PD1, and combination) to assess MR inhibition’s effect on immune responses through cell abundance and spatial reorganization. Anti-PD1 induced broad immune recruitment, especially neutrophils, while Trametinib had minimal effect. Combination therapy reduced neutrophil abundance below baseline, attenuating checkpoint blockade-induced neutrophil accumulation. NK/T cells, monocytes, and dendritic cells increased, while macrophages remained stable. Spatial analysis showed that anti-PD1 caused tumor cells to marginalize, while combination therapy partially restored integration. Neutrophils transitioned from marginalization to forming an immunological barrier around tumor cells, and NK/T cells interacted mainly with stromal/myeloid cells, indicating immune exclusion. Despite upregulating PD-L1 in all treatments, combination therapy induced PD-L1 expression without barrier formation, suggesting that spatial organization, not just ligand expression, drives neutrophil-mediated immune exclusion.\nConclusion: Treatments reshape tumor-immune architecture without disrupting tissue organization, relying on both immune cell abundance and their spatial distribution within the TME. Anti-PD1 induces broad immune infiltration, but neutrophils form a barrier limiting tumor penetration, which is relieved by the MR-inhibitor Trametinib. Neutrophils upregulate PD-L1 across all treatments, peaking after anti-PD1, while Trametinib and combination therapy drive PD-L1 expression without barrier formation.", "source_company": "Columbia University", "source_org_type": "大学", "row_number": 438, "target_meta": "PD1", "MOA_meta": "抑制剂"}, {"drug_name": "KDM2A inhibitor", "company": "UT MD Anderson Cancer Center", "org_type": "医院", "target": "KDM2A", "modality": "inhibitor", "importance_level": "低", "total_score": 46.5, "institution_score": 35, "track_score": 65, "milestone_score": 45, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "靶点为表观遗传酶KDM2A，在Barrett食管向食管腺癌进展中作为早期驱动因子，药理抑制可抑制肿瘤发生，但仅为学术机构preclinical机制研究，无具体药物分子和临床推进。机构为医院非药企、开发阶段早期导致总分较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/2092", "id": "zlXM_5wBX1NQZOEH-LG6", "source_drug_name": "KDM2A inhibitor", "title": "KDM2A-driven epigenetic reprogramming promotes barrett’s esophagus progression to adenocarcinoma", "abstract_text": "Purpose: Esophageal adenocarcinoma (EAC), a rapidly increasing and highly lethal cancer arising from Barrett’s esophagus (BE), lacks effective preventive strategies. Our study investigates the histone demethylase KDM2A as an early epigenetic driver of BE-to-EAC progression and evaluates whether its inhibition can suppress oncogenic reprogramming and tumorigenesis.\nExperimental Procedures: We performed high-plex spatial transcriptomics (COSMx, 1K human panel) on patient tissues spanning BE, low- and high-grade dysplasia, and EAC (n = 20), integrating these results with immunohistochemistry, immunofluorescence, and TCGA (n = 186) datasets. Functional studies employed patient-derived organoids (PDOs), xenografts, and CRISPR-based KDM2A perturbation models. Chromatin profiling (CUT&RUN for KDM2A, ATAC-seq, RNA-seq) was used to map KDM2A-dependent enhancer activation and tumor suppressor repression.\nResults: Spatial transcriptomics identified 13 transcriptional clusters delineating epithelial, stromal, and immune compartments. Progression from BE to EAC was characterized by expansion of stem-like epithelial clusters and loss of differentiation markers. PSCA and SPINK1 were consistently upregulated in EAC and correlated with increased EGFR expression, suggesting a convergence of these pathways in promoting therapy resistance and malignancy. KDM2A expression, validated by IHC/IF, was elevated in 4/6 EAC versus 1/3 BE samples and strongly correlated with PSCA and SPINK1. Analysis of TCGA-EAC confirmed KDM2A amplification and overexpression, which correlated with ERBB2, MYC, EGFR, and poor overall survival (p=8.67×10⁻³). Downstream analysis revealed repression of tumor suppressors DMBT1 and PFN1, implicating KDM2A in chromatin remodeling that silences protective loci while activating oncogenic enhancers. In organoid models, genetic or pharmacologic inhibition of KDM2A reduced PSCA/SPINK1 and EGFR signaling, restored differentiation, and suppressed proliferation.\nConclusions: KDM2A acts as a master chromatin regulator linking histone demethylation, tumor suppressor silencing, and activation of the PSCA-SPINK1-EGFR oncogenic axis during BE-to-EAC progression. Co-targeting KDM2A with EGFR/HER2 or MYC/CDK9 inhibitors represents a rational therapeutic strategy for early intervention and prevention. This study provides mechanistic insight into how epigenetic deregulation establishes a stem-like, therapy-resistant state in EAC and identifies KDM2A as a promising preventive and therapeutic target.", "source_company": "UT MD Anderson Cancer Center", "source_org_type": "医院", "row_number": 458, "target_meta": "KDM2A", "MOA_meta": "抑制剂"}, {"drug_name": "A2B inhibitor", "company": "Shengli Clinical Medical College of Fujian Medical University", "org_type": "大学", "target": "A2B", "modality": "inhibitor", "importance_level": "低", "total_score": 46.5, "institution_score": 25, "track_score": 75, "milestone_score": 45, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "药物为A2B受体抑制剂，靶向腺苷-A2B-CXCL13轴以改善老年PDAC免疫抑制微环境。机构为大学附属临床医学院，得分较低；虽腺苷通路在肿瘤免疫领域有一定热度，但仅停留在动物模型药理阻断阶段，缺乏明确临床开发进展。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10655", "id": "AlXM_5wBX1NQZOEH-LK6", "source_drug_name": "A2B inhibitor", "title": "Adenosine-driven inflammatory reprogramming of aged cancer-associated fibroblasts promotes immune suppression in pancreatic ductal adenocarcinoma", "abstract_text": "Background: Aging exerts a profound influence on the tumor immune microenvironment of pancreatic ductal adenocarcinoma (PDAC). In elderly patients, PDAC is frequently characterized by pronounced stromal desmoplasia, enhanced immune evasion, and increased resistance to chemotherapy. The molecular underpinnings of these age-associated alterations remain largely undefined. Emerging evidence indicates that aging-related metabolic reprogramming can profoundly reshape the cellular and immunologic composition of the tumor microenvironment (TME). Yet, the mechanistic interplay between metabolic perturbations, stromal cell dynamics, and immune regulation in aged PDAC has not been fully elucidated.\nMethods: Two PDAC clinical cohorts stratified by age and survival were analyzed using bulk and single-cell transcriptomics, and metabolomics. Nucleotide metabolism was assessed by targeted metabolomics. Functional studies included adenosine stimulation of aged and young cancer-associated fibroblasts (CAFs), B cell migration and co-culture assays, cytokine profiling, and orthotopic PDAC mouse models with adenosine receptor blockade. Multiplex immunohistochemistry (mIHC) was applied to spatially validate the proximity of A2B⁺CXCL13⁺ CAFs and IL-10⁺ Bregs in aged human PDAC tissues.\nResults: Aged PDAC exhibited increased regulatory B (Breg) cell abundance, which correlated with shorter overall survival. Multi-omic analyses identified age-related adenosine accumulation as the most dysregulated metabolite linked to both poor prognosis and Breg infiltration. Direct adenosine exposure failed to expand Bregs but reprogrammed aged CAFs toward a proinflammatory state. Aged CAFs expressed elevated adenosine receptor A2B and secreted the B cell chemoattractant CXCL13 upon adenosine stimulation. The adenosine-A2B-CXCL13 axis promoted IL-10⁺ Breg recruitment, which suppressed CD8⁺ T cell cytotoxicity and accelerated tumor growth. mIHC confirmed close spatial association between CXCL13⁺ CAFs and Bregs within aged PDAC tissues. Pharmacologic inhibition of A2B signaling or CXCL13 neutralization reduced Breg infiltration, restored T cell activity, and prolonged survival in orthotopic aged PDAC models.\nConclusion: Age-associated adenosine accumulation reshapes the fibroblastic niche through A2B receptor-dependent inflammatory reprogramming, inducing CXCL13-mediated Breg recruitment and immune suppression. Targeting the adenosine-A2B-CXCL13 axis represents a promising strategy to restore anti-tumor immunity in elderly patients with PDAC.", "source_company": "Shengli Clinical Medical College of Fujian Medical University", "source_org_type": "大学", "row_number": 491, "target_meta": "ADORA2B", "MOA_meta": "抑制剂"}, {"drug_name": "duocarmycin-based ADC", "company": "University of Bradford", "org_type": "大学", "target": "未披露", "modality": "ADC", "importance_level": "低", "total_score": 46.5, "institution_score": 25, "track_score": 85, "milestone_score": 35, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "新型duocarmycin类ADC payload设计，靶点未披露，modality为ADC属于热门赛道，但由大学机构开展，处于早期化学合成与体外细胞水平研究，尚未进入in vivo或临床阶段。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8784", "id": "iVXM_5wBX1NQZOEH-LK6", "source_drug_name": "duocarmycin-based ADC", "title": "Design, synthesis, and biological investigation of a new class of duocarmycin payloads for ADC development", "abstract_text": "Introduction: The duocarmycins belong to a class of agent that has been in the interest of chemist and drug developers for over four decades. Their pico-molar cellular potency, unique mechanism of action, and efficacy against drug-resistant cancer cells makes them attractive as payloads for inclusion in antibody-drug conjugate (ADC) discovery approaches. However, despite great advances in fine-tuning biological activity through structure-activity relationship (SAR) studies, no duocarmycin-based therapeutic has reached clinical approval. Recent duocarmycin-based ADCs under clinical evaluation have been hampered by a narrow therapeutic index, which have inspired us to modulate the duocarmycin scaffold designed by nature. Here we present our design approach, synthesis and biological investigation of new duocarmycin chemotypes.\nMethodology: Seco-duocarmycins derived from common scaffolds such as CBI and CPI are precursor molecules where the phenolic OH group essential for spirocyclisation was converted into a triflate. The latter was subjected to (i) Suzuki chemistry to generate novel aryl C-C linked compounds or (ii) or Buchwald-Hartwig reaction to generate aniline-linked duocarmycin target molecules. Subsequently, modulated compounds were studied for their ability to spirocyclise (LCMS), cause DNA damage using γ-H2AX as marker and produce antiproliferative effects in a panel of breast, colon, ovarian, prostate cancer and rhabdomyosarcoma cell lines (MTT assay).\nResults: Biochemical assays revealed that these analogues exhibit a slower spirocyclization rate (2-48 hours) compared to the control compounds CPI-MI and CBI-MI (< 90 min). The library of duocarmycin payloads exhibited a wide range of cellular potencies in our panel of cancer cell lines (0.1 - 1000 nM), retaining antiproliferative activity in doxorubicin (MCF7adr) and docetaxel-resistant (PC3-D8) cancer cell lines whilst also be unaffected by the p53 status (HCT116 p53+/+ and p53-/-).\nConclusion: New duocarmycin chemotype design offers an opportunity to reduce spirocyclisation rate and DNA reactivity to fine-tune cellular potency. We hypothesise incorporation of these promising payloads into ADC therapeutics will improve tumour biodistribution, bystander effect and reduce normal tissue toxicity.", "source_company": "University of Bradford", "source_org_type": "大学", "row_number": 574, "target_meta": "not available", "MOA_meta": "抗体偶联药物"}, {"drug_name": "SPOP inhibitor", "company": "Mayo Clinic", "org_type": "医院", "target": "SPOP", "modality": "inhibitor", "importance_level": "中", "total_score": 46.5, "institution_score": 35, "track_score": 65, "milestone_score": 45, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "靶向SPOP的抑制剂可逆转AR-V7介导的ARPI耐药，通过影响剪接体机制降低AR-V7表达。Mayo Clinic作为医院机构研发早期，机制新颖但仍处preclinical阶段，整体重要性中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3763", "id": "qVXM_5wBX1NQZOEH-LK6", "source_drug_name": "SPOP inhibitor", "title": "SPOP drives AR-V7-mediated ARPI resistance in prostate cancer", "abstract_text": "Approximately 288,000 men are diagnosed with prostate cancer (PCa) in the United States each year, with cases expected to double by 2040. While metastatic PCa can be treated with androgen deprivation therapy (ADT) and AR pathway inhibitors (ARPI), it inevitably develops into treatment resistant, lethal disease. The most common ARPI resistance mechanism in PCa is the expression of AR splice variant AR-V7 that lacks the ligand binding domain and is constitutively active. Patients with PCa expressing AR-V7 experience inferior overall survival. Speckle-type POZ protein (SPOP) is an adaptor protein of the Cullin3-based E3 ubiquitin ligase that facilitates both degradative and non-degradative polyubiquitination of targets such as AR. Loss-of-function SPOP mutations occur in approximately 10-15% of prostate cancers, and SPOP-mutant PCa is a unique subtype that has been shown to be exquisitely sensitive to ADT and ARPI treatment. This sensitivity is mediated in part by increased androgen availability via upregulation of hydroxysteroid 17-beta dehydrogenase 4 (HSD17B4) and related steroid synthesis pathways, reduced AR degradation, and enhanced AR cofactor activity. The remarkable efficacy of ARPI in ADT-resistant SPOP-mutant prostate cancer is not well understood.We hypothesized a novel mechanism by which wild-type SPOP promotes AR-V7-mediated resistance to ARPI in PCa. This mechanism may explain the exceptional ARPI sensitivity of SPOP-mutant PCa, distinct from its susceptibility to ADT. We further proposed that clinical SPOP inhibition may broaden this enhanced ARPI susceptibility to the 85-90% of PCa expressing wild-type SPOP.Our results show that SPOP drives ARPI resistance in prostate cancer that can be reversed by SPOP inhibitor. Bulk RNA sequencing showed that SPOP inhibitor targets spliceosome machinery and more importantly, abrogated AR-V7 expression both at transcriptional and protein level. Further investigation revealed that wild-type SPOP ubiquitinates spliceosome regulator SFPQ, promoting AR-V7 alternative splicing and ARPI resistance. While SPOP loss is pathogenic in PCa, leveraging the weakness conferred by SPOP mutation in the 85% of patients with SPOP-wild type provides an innovative strategy to sensitize ARPI resistant disease to standard of care treatment and save lives.", "source_company": "Mayo Clinic", "source_org_type": "医院", "row_number": 596, "target_meta": "SPOP", "MOA_meta": "抑制剂"}, {"drug_name": "senolytic drugs", "company": "The University of Osaka", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 46.5, "institution_score": 30, "track_score": 75, "milestone_score": 40, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "senolytic drugs为清除衰老细胞的药物类别，未明确具体靶点或单一药物，机制涉及线粒体调控但非肿瘤靶向新药。机构为大学学术型，非头部药企；赛道为抗衰老热门但非肿瘤主流，AACR会议摘要禁运无明确里程碑进展，故整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11583", "id": "xFXM_5wBX1NQZOEH-LK6", "source_drug_name": "senolytic drugs", "title": "Comparative analysis of senolytic drugs reveals mitochondrial determinants of efficacy and resistance", "abstract_text": "Abstract is embargoed at this time.", "source_company": "The University of Osaka", "source_org_type": "大学", "row_number": 611, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "PARP inhibitor", "company": "Shenzhen University General Hospital", "org_type": "医院", "target": "PARP1", "modality": "inhibitor", "importance_level": "中", "total_score": 46.5, "institution_score": 25, "track_score": 75, "milestone_score": 45, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "摘要聚焦PARP抑制剂靶向alt-EJ通路（PARP1）逆转miR-21-5p介导的OSCC放疗抵抗，机制明确但仅为学术研究层面验证。机构为医院非药企、仍处于机制+动物模型阶段导致总体重要性中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3981", "id": "N1XM_5wBX1NQZOEH-LO6", "source_drug_name": "PARP inhibitor", "title": "Targeting alternative end-joining overcomes miR-21-5p-mediated radioresistance in oral squamous cell carcinoma", "abstract_text": "Radiation resistance remains a major barrier to effective radiotherapy in oral squamous cell carcinoma (OSCC), yet its molecular basis is incompletely defined. Here, we uncover activation of the alternative end‑joining (alt‑EJ) DNA repair pathway as a key driver of miR‑21‑5p-mediated radioresistance in OSCC. Comprehensive miRNA profiling of radioresistant OSCC clones revealed distinct expression signatures marked by robust upregulation of miR‑21‑5p and miR‑486‑5p, coupled with reduced miR‑320b and miR‑1248. Functional assays, including clonogenic survival and syngeneic mouse tumor models, demonstrated that enforced expression of miR‑21‑5p markedly enhanced radioresistance, accompanied by sustained DNA damage response signaling and improved double‑strand break (DSB) repair capacity. Transcriptomic and genomic analyses of the TCGA‑HNSC cohort revealed that high miR‑21‑5p expression correlates with suppression of canonical DNA repair targets, poor radiotherapy outcomes, elevated tumor mutational burden (TMB), and an increased frequency of microhomology‑mediated insertions/deletions, consistent with heightened alt‑EJ activity. Cross‑validation in independent OSCC datasets and local tumor panels confirmed that miR‑21‑5p-overexpressing tumors exhibit strong activation of alt‑EJ gene programs, including upregulation of PARP1, POLQ, and associated accessory factors. Analysis of diverse cancer cell line databases further established that miR‑21‑5p activity positively correlates with alt‑EJ gene expression independent of microenvironmental influence. Mechanistically, miR‑21‑5p overexpression shifted DSB repair dependence from homologous recombination and classical non‑homologous end‑joining toward alt‑EJ. Pharmacologic or genetic suppression of alt‑EJ components (PARP1 or POLQ) disrupted DSB resolution and effectively restored radiosensitivity in miR‑21‑5p-high OSCC cells. Notably, radiosensitization by PARP inhibition was abrogated in POLQ‑deficient cells, confirming a POLQ‑dependent mechanism. In vivo, miR‑21‑5p-driven OSCC tumors exhibited enhanced expression of alt‑EJ signatures, increased radioresistance, and high TMB. Combination treatment with irradiation and PARP blockade suppressed tumor growth, diminished alt‑EJ gene expression, and prolonged survival in a syngeneic mouse model. Collectively, these findings establish a novel miR‑21‑5p/alt‑EJ signaling axis as a central determinant of radioresistance in OSCC. Targeting alt‑EJ represents a promising therapeutic strategy to overcome miR‑21‑5p-mediated treatment failure and improve radiotherapy efficacy in head and neck cancers.", "source_company": "Shenzhen University General Hospital", "source_org_type": "医院", "row_number": 689, "target_meta": "PARP1", "MOA_meta": "抑制剂"}, {"drug_name": "BioRNA/let-7e-5p", "company": "UC Davis School of Medicine", "org_type": "大学", "target": "未披露", "modality": "mRNA", "importance_level": "低", "total_score": 46.5, "institution_score": 35, "track_score": 65, "milestone_score": 45, "field_heat_score": 55, "bonus_score": 2, "brief_reason": "BioRNA/let-7e-5p为生物工程化肿瘤抑制miRNA，主要针对NSCLC细胞，靶点未明确披露。大学机构+preclinical优化阶段导致总体重要性较低，但miRNA生物工程平台和s4U修饰去除具有一定技术亮点。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/2350", "id": "YFXM_5wBX1NQZOEH-LO6", "source_drug_name": "BioRNA/let-7e-5p", "title": "The impact of 4-thiouridine posttranscriptional modification on the oncosuppressive activity of bioengineered let-7e-5p in NSCLC cells", "abstract_text": "Current microRNA (miRNA) research and therapeutic development primarily rely on miRNA mimics chemically synthesized in vitro. While effective, miRNA mimics may not fully recapitulate the properties of natural miRNA agents synthesized in vivo. Our lab has developed a novel tRNA-fused pre-miRNA carrier-based RNA bioengineering platform technology, enabling consistent, high-yield, and large-scale production of biologic miRNAs (BioRNAs) through in vivo bacterial fermentation, which have shown strong potential in experimental therapeutics for non-small cell lung cancer (NSCLC). Among the tumor suppressive let-7-5p isoforms, BioRNA/let-7e-5p was identified as the most effective to suppress human NSCLC cell viability. Further, while we observed species-conserved posttranscriptional modifications, such as dihydrouridine (D) and 2′-O-methylguanosine (Gm) in the D-loop as well as 5-methyluridine (m5U) and pseudouridine (Y) in the T-loop, liquid chromatography tandem mass spectrometry (LC-MS/MS) and nanopore-based direct RNA sequencing studies revealed the presence of a bacteria-specific 4-thiouridine (s4U) modification at position 8 (s4U8) of the human tRNA segment. To re-innovate our BioRNA technology and generate BioRNA/let-7e-5p molecules free of s4U modification, we employed two strategies: (1) change of U8 through deletion or substitutions, and (2) expression of U8 BioRNAs in an E. coli strain deficient in s4U synthesis. Both approaches proved successful, allowing us to produce milligrams of pure, ready-to-use BioRNA/let-7e-5p molecules per 200 mL bacterial culture, and LC-MS/MS and nanopore sequencing analyses confirmed the escape from s4U modification. Surprisingly, comprehensive comparative studies showed minimal effects of the distal s4U modification on the release of let-7e-5p from BioRNAs and consequently, downregulation of multiple targeted oncogenes in NSCLC cells. These findings will guide the development of BioRNA/let-7e-5p as potential therapeutics for NSCLC treatment.", "source_company": "UC Davis School of Medicine", "source_org_type": "大学", "row_number": 714, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "KIFC1 inhibitor", "company": "The University of Tokyo", "org_type": "大学", "target": "KIFC1", "modality": "inhibitor", "importance_level": "低", "total_score": 46.5, "institution_score": 25, "track_score": 55, "milestone_score": 65, "field_heat_score": 50, "bonus_score": 3, "brief_reason": "KIFC1抑制剂通过诱导小细胞肺癌中的anaphase catastrophe实现选择性抗肿瘤效应，机制新颖但靶点非热门。大学机构、非热门赛道、仅限于体外+异种移植模型导致整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3461", "id": "qFXM_5wBX1NQZOEH-LO6", "source_drug_name": "KIFC1 inhibitor", "title": "Targeting KIFC1 induces anaphase catastrophe in small cell lung cancer", "abstract_text": "Cancer cells often possess more than two centrosomes, which is one of the hallmarks of cancer. By clustering these supernumerary centrosomes during mitosis, cancer cells can achieve bipolar division. We previously reported that in non-small cell lung cancer, CDK2 inhibition suppresses centrosome clustering, leading to multipolar cell division and apoptotic cell death—a phenomenon termed anaphase catastrophe. Because normal cells have only two centrosomes, anaphase catastrophe does not appreciably affect them, making it a promising therapeutic strategy for selectively eliminating cancer cells. However, as CDK2 inhibition also interferes with normal cell cycle progression, identifying therapeutic targets that can induce anaphase catastrophe preferentially is desirable. Motor protein KIFC1 has been implicated in centrosome clustering. Here, we investigated its potential as a novel therapeutic target to induce anaphase catastrophe in small cell lung cancer (SCLC). Owing to p53 inactivation, SCLC is expected to frequently harbor supernumerary centrosomes and be vulnerable to mitotic abnormalities, including anaphase catastrophe. First, in vitro experiments using multiple SCLC cell lines were conducted. Immunofluorescence staining for pericentrin confirmed that centrosome amplification occurs more frequently in SCLC cells than in normal human bronchial epithelial (NHBE) cells. Western blotting revealed that KIFC1 was overexpressed in SCLC cells as compared with NHBE cells. Functional analyses, both pharmacologic (using a specific inhibitor) and genetic (using siRNAs and the CRISPR-Cas9 system), demonstrated that inhibition of KIFC1 induced apoptosis and suppressed proliferation in SCLC cell lines, whereas these effects were largely absent in NHBE cells. Furthermore, immunostaining for α-tubulin, pericentrin, and DAPI showed a statistically significant increase in multipolar mitotic cells and a decrease in cells with clustered supernumerary centrosomes among dividing cells, implicating KIFC1 inhibition in conferring anaphase catastrophe in SCLC. These findings were validated and extended in the in vivo setting. In human SCLC cell-derived xenograft models, administration of KIFC1 inhibitor statistically significantly suppressed tumor growth. Staining of excised tumors for pericentrin revealed reduced numbers of cells with clustered supernumerary centrosomes and increased numbers undergoing multipolar mitosis, consistent with in vitro findings and indicative of anaphase catastrophe induction. Finally, potential combination therapies with other pharmacologic targets were explored and will be presented. In conclusion, inhibition of KIFC1 disrupts the clustering of supernumerary centrosomes and caused anaphase catastrophe, indicating its promise as a novel therapeutic target for SCLC.", "source_company": "The University of Tokyo", "source_org_type": "大学", "row_number": 763, "target_meta": "KIFC1", "MOA_meta": "抑制剂"}, {"drug_name": "Her2-targeted p53 mRNA-LNP", "company": "Samsung Medical Center", "org_type": "医院", "target": "HER2", "modality": "mRNA", "importance_level": "低", "total_score": 46.5, "institution_score": 30, "track_score": 75, "milestone_score": 40, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "药物通过HER2靶向递送p53 mRNA-LNP恢复p53功能以克服p53缺陷卵巢癌放疗抵抗，机制为靶向递送肿瘤抑制基因mRNA；三星医疗中心为医院机构非商业药企、摘要仍处于embargo缺乏开发阶段细节导致总体评分较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11477", "id": "DVXM_5wBX1NQZOEH-LS6", "source_drug_name": "Her2-targeted p53 mRNA-LNP", "title": "Her2-targeted p53 mRNA-LNP platform: A novel strategy for overcoming radioresistance in p53-deficient ovarian cancer", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Samsung Medical Center", "source_org_type": "医院", "row_number": 841, "target_meta": "HER2", "MOA_meta": "其他"}, {"drug_name": "2-PMPA", "company": "Ehime University Graduate School of Medicine", "org_type": "大学", "target": "PSMA", "modality": "inhibitor", "importance_level": "低", "total_score": 46.5, "institution_score": 25, "track_score": 65, "milestone_score": 55, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "2-PMPA为PSMA小分子抑制剂，在RCC肿瘤血管中显示抗血管生成作用并抑制肿瘤生长，但仅为大学机构的体外+小鼠异种移植模型研究，缺乏临床转化迹象。机构非药企+仍处于早期探索阶段导致总体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1524", "id": "SVXM_5wBX1NQZOEH-LS6", "source_drug_name": "2-PMPA", "title": "PSMA-expressing tumor vasculature in renal cell carcinoma: spatial, functional, and therapeutic implications", "abstract_text": "Background\nProstate-specific membrane antigen (PSMA) is an established diagnostic and therapeutic target in prostate cancer, widely utilized in PSMA-PET imaging and PSMA-directed radioligand therapy. Beyond prostate cancer, PSMA has also been reported in the tumor-associated vasculature of several solid tumors, suggesting its potential as a vascular marker and therapeutic target. In renal cell carcinoma (RCC), PSMA-positive vessels have been described, yet their spatial distribution, mechanisms of induction, contribution to angiogenesis, and therapeutic relevance remain insufficiently defined.\nMethods\nSpatial transcriptomic analysis (10x Genomics Visium) was performed to characterize the spatial localization of FOLH1 (PSMA) expression and associated transcriptional changes within RCC tissues. Immunohistochemistry for PSMA and CD31 was conducted on 45 RCC cases to evaluate associations with recurrence and venous invasion. Endothelial cells were exposed to RCC-derived conditioned medium and differential centrifugation fractions to assess PSMA induction, angiogenic activity, and transcriptional alterations. A Caki1 xenograft model was used to investigate the therapeutic effect of the PSMA inhibitor 2-PMPA.\nResults\nSpatial analysis showed that FOLH1 expression was concentrated within peritumoral vascular regions and overlapped with areas exhibiting increased expression of angiogenesis-related genes. Immunohistochemistry confirmed that PSMA expression was restricted to tumor-associated vessels, and strong PSMA expression was significantly associated with recurrence and venous invasion. Among RCC-derived fractions, only the 10,000 g pellet robustly induced endothelial PSMA expression, enhanced tube formation, and activated angiogenesis-related transcriptional programs. In vivo, treatment with 2-PMPA significantly reduced tumor growth and microvessel density.\nConclusions\nPSMA-positive vasculature in RCC represents an endothelial phenotype induced by tumor-derived vesicles and functionally contributes to angiogenesis. The association between strong PSMA expression and aggressive clinicopathologic features, together with the anti-angiogenic effect of PSMA inhibition, highlights PSMA-positive vessels as a promising therapeutic target in RCC. These findings provide a molecular basis for extending PSMA-targeted imaging and therapeutic strategies—well established in prostate cancer—to PSMA-positive RCC.", "source_company": "Ehime University Graduate School of Medicine", "source_org_type": "大学", "row_number": 883, "target_meta": "PSMA", "MOA_meta": "抑制剂"}, {"drug_name": "EGFR tyrosine kinase inhibitors", "company": "UCSF Helen Diller Family Comprehensive Cancer Center", "org_type": "医院", "target": "EGFR", "modality": "inhibitor", "importance_level": "低", "total_score": 46.5, "institution_score": 35, "track_score": 75, "milestone_score": 30, "field_heat_score": 65, "bonus_score": 0, "brief_reason": "该条目讨论EGFR TKI耐药机制及肿瘤-巨噬细胞交互作用，非新药或具体候选药物研发，靶点为EGFR，modality为inhibitor。机构为医院/学术中心且无明确药物开发里程碑，导致整体重要性评分较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4946", "id": "kVXM_5wBX1NQZOEH-LS6", "source_drug_name": "EGFR tyrosine kinase inhibitors", "title": "Tumor-macrophage crosstalk promotes resistance to EGFR targeted therapy in lung adenocarcinoma", "abstract_text": "Lung cancer remains the leading cause of cancer-related mortality worldwide. Non-small cell lung cancer (NSCLC) is the predominant histologic subtype, with lung adenocarcinoma the most common form of NSCLC. Approximately 15-20% of lung adenocarcinomas harbor activating mutations in the tyrosine kinase domain of the epidermal growth factor receptor (EGFR). Although targeted therapies have substantially improved clinical outcomes for patients with EGFR-mutant NSCLC, most patients do not achieve complete response, underscoring the need to elucidate mechanisms of resistance to EGFR tyrosine kinase inhibitors (TKIs). We hypothesize that, in addition to tumor-cell-intrinsic mechanisms, interactions between cancer cells and the tumor microenvironment could contribute to treatment resistance. Leveraging clinical sequencing data alongside cell co-culture systems, organoid models, and in vivo studies, we show that TKI-treated EGFR-mutant cells upregulate cytokines and chemokines that promote recruitment and maintenance of tumor-infiltrating macrophages, a population associated with poor clinical outcomes. Moreover, interactions between therapy-treated cancer cells and newly recruited macrophages support tumor survival by enhancing cancer cell viability and reducing phagocytic clearance. Genetic and molecular profiling further reveal that soluble pro-inflammatory mediators secreted by macrophages, including TNF-ɑ and IL-1β, engage the NF-κB signaling pathway in EGFR-mutant cells, thereby driving residual disease and resistance. Together, these findings provide a rationale for disrupting microenvironmental crosstalk between EGFR-mutant tumor cells and tumor-infiltrating macrophages as a strategy to limit residual disease. Targeting these interactions may enable a new class of microenvironment-directed therapies to overcome resistance to EGFR TKIs.", "source_company": "UCSF Helen Diller Family Comprehensive Cancer Center", "source_org_type": "医院", "row_number": 936, "target_meta": "EGFR", "MOA_meta": "抑制剂"}, {"drug_name": "HDAC class IIb inhibitors", "company": "Georgetown Lombardi Comprehensive Cancer Center", "org_type": "医院", "target": "HDAC class IIb", "modality": "inhibitor", "importance_level": "低", "total_score": 46.5, "institution_score": 35, "track_score": 65, "milestone_score": 40, "field_heat_score": 55, "bonus_score": 0, "brief_reason": "靶向HDAC class IIb的选择性抑制剂，通过重编程GAMs/小胶质细胞表型增强GBM免疫杀伤作用。机构为医院/学术中心且仅处于体外+初步机制研究阶段，整体开发里程碑价值有限。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9569", "id": "p1XM_5wBX1NQZOEH-LS6", "source_drug_name": "HDAC class IIb inhibitors", "title": "Reprogramming microglial and GAMs phenotype and function, with HDAC inhibitors to overcome immune suppression in glioblastoma", "abstract_text": "Glioblastoma multiforme (GBM) stands as the most aggressive form of primary tumor in the central nervous system, primarily affecting older male individuals. The immune landscape in GBM is significantly influenced by Glioma-associated microglia and infiltrating macrophages (GAMs), which together account for up to 45% of the tumor mass. These cells are highly plastic and can shift their phenotype between tumor-fighting, pro-inflammatory (M1-like) and tumor-supportive, anti-inflammatory (M2-like) states in response to different environmental cues. Epigenetic regulation of this plasticity has emerged as a promising therapeutic strategy to reprogram innate immunity within the TME. Here, we demonstrated that selective class IIb HDAC inhibitor treatment reprograms primarily macrophages and microglia toward a pro-inflammatory, phagocytic, and tumor-killing state. Using the BV2 microglial cell line and bone marrow-derived macrophages, we found that HDAC class IIb inhibitors increased M1 markers, decreased M2 phenotype, and enhanced phagocytosis. Interestingly, they enhanced microglial migration in both M1-like and M2-like cells, potentially reflecting the innate migratory capacity of these resident immune cells in the brain, which are constantly surveilling and rapidly responding to environmental cues. In contrast, these class IIb inhibitors reduced macrophage migration, underscoring the functional divergence between these cell types. To further validate our findings in a physiologically relevant system, we optimized a robust high-purity primary microglia isolation protocol from murine brains. Future work includes transcriptomic profiling and in vivo studies to assess therapeutic efficacy and immune remodeling. Our results support HDAC class IIb inhibition as a promising strategy to modulate immune responses in GBM and suggest that targeting myeloid cell plasticity may enhance the efficacy of immunotherapeutic responses in GBM.", "source_company": "Georgetown Lombardi Comprehensive Cancer Center", "source_org_type": "医院", "row_number": 954, "target_meta": "not available", "MOA_meta": "抑制剂"}, {"drug_name": "TRAIL", "company": "National Institute of Health", "org_type": "研究机构", "target": "TRAIL receptor", "modality": "other", "importance_level": "低", "total_score": 46.5, "institution_score": 45, "track_score": 55, "milestone_score": 35, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "TRAIL作为TNF家族配体通过死亡受体诱导肿瘤细胞凋亡，但临床疗效受限，该研究聚焦其在TNBC中诱导免疫抑制性中性粒细胞的机制而非药物开发。机构为NIH但处于基础科研阶段、无明确药物里程碑，赛道非当前热门，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6071", "id": "OZ7M_5wBZznHJdnt_W3O", "source_drug_name": "TRAIL", "title": "Deciphering neutrophil heterogeneity to enhance therapeutic efficacy of TRAIL (Tumor necrosis factor-related apoptosis-inducing ligand) in triple negative breast cancers", "abstract_text": "TRAIL induces apoptosis in many preclinical cancer models including breast cancer models and has been extensively studied as a potential cancer therapeutic target. However, the clinical efficacy of TRAIL agonists is limited, suggesting that there are unknown modulatory mechanisms responsible for the lack of activity in patients. Our prior work demonstrated that TRAIL induces various cytokines (CXCL1, CXCL2, CXCL3, CXCL8, CXCL11, IL6) via NFKB2-dependent pathway in triple negative breast cancers (TNBC), promoting the recruitment of immunosuppressive neutrophils, suggesting that neutrophil-mediated regulation of the tumor immune microenvironment modulates TRAIL activity in TNBC. Thus, this study aims 1) to characterize the neutrophil heterogeneity induced by TRAIL as well as derived factors from TRAIL treated TNBC, and 2) to identify targetable pathways that could reprogram neutrophils towards an anti-tumor phenotype, thus enhancing TRAIL efficacy. To address this, neutrophils isolated from a healthy donor were incubated with 4 different conditions: serum-free media (SFM), SFM supplemented with TRAIL (SFM-T), conditioned media from TNBC (CM), or conditioned media from TRAIL-treated TNBC (T-CM). Single cell RNA sequencing (scRNA-seq) of neutrophils (43,420 cells) across the 4 conditions indicated that there are 10 transcriptionally distinct clusters. These findings were further validated with scRNA-seq of pooled neutrophils from 5 different healthy individuals (35,500 cells). t-SNE analysis identified similar transcriptionally distinct states encompassing inflammation, antigen presentation, and ribosome biogenesis programs, demonstrating remarkable neutrophil heterogeneity. Based on literature and functional relevance, we focused on 2 key clusters that were increased upon treatment of the neutrophils with T-CM identified in both experiments. One is enriched for antigen-presentation genes and immunosuppressive markers such as CCL4, CD274, IL1A, and IL1B, and a second enriched for ribosome biogenesis-related genes including DDX21, UTP18, LAGE3, and NPM1. These clusters also exhibited low expression of IFN-gamma/alpha-responsive genes, further suggesting the immunosuppressive role of T-CM. In contrast, SFM-T treatment resulted in a population with markers regulating neutrophil-specific function (e.g. NETosis, degranulation). The Sc-RNA-seq findings are currently being confirmed by gene expression analysis and surface staining methods. Collectively, our study delineates a potential mechanistic role of supernatants from TRAIL treated TNBC cells and neutrophil plasticity. These findings imply that targeting the innate immune system may modulate the effects of TRAIL on TNBC tumors enhancing the therapeutic outcomes.", "source_company": "National Institute of Health", "source_org_type": "研究机构", "row_number": 987, "target_meta": "TRAILR", "MOA_meta": "其他"}, {"drug_name": "Verbascoside", "company": "University of Illinois at Chicago", "org_type": "大学", "target": "CD44", "modality": "inhibitor", "importance_level": "低", "total_score": 46.5, "institution_score": 35, "track_score": 65, "milestone_score": 40, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "Verbascoside作为CD44小分子拮抗剂，在体外阻断MIF-CD44信号抑制肺上皮细胞恶性转化。大学机构preclinical早期研究，靶点与机制有一定新颖性但开发阶段早、机构非商业化主体导致总体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9852", "id": "pZ3ECZ0B4z9FlvORyiZD", "source_drug_name": "Verbascoside", "title": "Stearic acid-macrophage crosstalk identifies MIF-CD44 signaling as a therapeutic target in lung cancer initiation", "abstract_text": "Background: Lung cancer (LC) is the leading cause of cancer-related mortality, yet the process of tumor initiation is poorly understood. Prior work from our group indicated that biomolecules like stearic acid (SA) and proinflammatory cytokines like MIP1α and MIP1β were selectively elevated in the tumor bearing lung lobes of early-stage LC patients. Hence, we hypothesized that a SA-macrophage (MΦ) inflammatory axis contributes to neoplastic transformation in lung epithelium.\nMethod: Plasma cytokine profiles were compared between early-stage LC patients (n=5) and healthy controls (n=6). Cytokine production following SA exposure at transcriptional and translational level were assessed in PBMC-derived MΦs and human monocytic cell lines (U937) to establish synchrony between two systems. Conditioned media (CM) from SA-treated MΦs (SA-CM) was applied to BEAS2B epithelial cells (non-transformed lung epithelial cells), with transformation measured by soft agar and spheroid assays. Receptor expression for MIP1α (CCR5) and MIF (CD44) was quantified by mRNA/protein analyses. Functional blockades of CCR5 and CD44 were performed using small-molecule antagonists (Maraviroc and Verbascoside respectively) to identify critical cytokine driving transformation.\nResults: Elevated MIP1α were observed in plasma samples from early-stage LC patients compared to healthy individuals. SA treatment augmented MIP1α and MIF expression from both PBMC and U937 derived MΦs. Simultaneously, SA-CM from both PBMC and U937 derived MΦs induced significantly greater colony formation in soft agar matrix and robust spheroid growth under low-attachment conditions, indicating neoplastic transformation. Receptor analysis revealed abundant CD44 but limited CCR5 expression on BEAS2B cells. Blockade of CD44 with Verbascoside abrogated SA-CM-induced spheroid formation, whereas CCR5 inhibition had no effect.\nConclusion: Based on these observations we conclude that SA reprograms MΦ transcriptional states promoting a MΦ driven proinflammatory environment that induces MIF-CD44-dependent neoplastic transformation of lung epithelial cells. These findings implicate a novel immunometabolic axis involved in the early oncogenic events of LC initiation and support therapeutic targeting of SA-MIF-CD44 signaling as a potential preventive strategy.", "source_company": "University of Illinois at Chicago", "source_org_type": "大学", "row_number": 1047, "target_meta": "CD44", "MOA_meta": "抑制剂"}, {"drug_name": "SIAH2PD", "company": "Eastern Virginia Medical School", "org_type": "大学", "target": "SIAH", "modality": "other", "importance_level": "低", "total_score": 46.5, "institution_score": 30, "track_score": 75, "milestone_score": 40, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "SIAH2PD为SIAH抑制剂（基于DOX诱导表达系统，疑似显性负性或抑制性构建体），靶向K-RAS通路下游关键E3连接酶SIAH，具有阻断肿瘤信号、诱导凋亡和肿瘤清除的preclinical潜力。机构为大学，preclinical阶段机制研究为主，无产业化进展，导致总体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1847", "id": "sp7M_5wBZznHJdnt_W3O", "source_drug_name": "SIAH2PD", "title": "Eradicating metastatic cancers by targeting a major tumor vulnerability of the K-RAS pathway: Seven in absentia homolog (SIAH)", "abstract_text": "Background: Persistent activation of the K-RAS pathway is multipotent: its downstream signaling networks promote tumorigenesis, drug resistance, relapse, and metastasis. Despite newly developed state-of-the-art therapies, none have yet to achieve durable antitumor efficacy. Seven in absentia homologues (SIAHs) are a conserved family of RING-domain E3 ubiquitin ligases that function as the most downstream signaling gatekeepers in the K-RAS pathway. Our preclinical studies demonstrated that SIAH inhibition leads to a tumor eradication phenotype of multiple stage IV human cancer cell lines both in vitro and in vivo.\nAims: We propose SIAH is a major tumor vulnerability and actionable drug target for inhibiting K-RAS pathway activation. In this study, we aim to elucidate the molecular mechanisms underpinning the antitumor efficacy of our potent SIAH inhibitor, SIAH2PD, as a new targeted therapy to achieve tumor eradication.\nMethods: Reverse phase protein arrays (RPPAs) and principal component analysis (PCA) were used to quantify statistically significant fold-changes of 294 signaling proteins and phospho-proteins in response to SIAH blockade in five stage IV cell lines. RPPAs were performed in triplicate on MiaPaCa, MDA-MB-231, MDA-MB-468, HeLa, and A459 cell lines in which SIAH2PD expression was controlled by a doxycycline (DOX)-inducible Tet-ON/OFF system. Four experimental conditions were used: Tet-ON vector control cells without DOX (group A) and with DOX induction (group B); Tet-ON-SIAH2PD experimental cells without DOX (group C) and with DOX induction (group D). The ratios of each group were calculated in a pairwise comparison after normalization to GAPDH as an internal control. To validate putative targets of interest, immunofluorescence (IF), flow cytometry (FC), and Western blots (WB) were performed on cells for group C and D at 3-, 5-, and 7-days post-DOX-induction. Adherent and single cell suspensions were used respectively for cell-based assays in biological triplicates and normalized to α-Tubulin. Target protein expression was quantified and validated, and statistical analyses were performed by one-way ANOVA and T-tests using GraphPad Prism software.\nResults: The altered expression of NFκB, Caspase-3, Caspase-7, Cofilin, and PARP in response to SIAH blockade were independently validated by RPPA, WB, FC, and IF, demonstrating the roles of heightened cellular stress, apoptosis, and dysfunctional DNA damage and repair pathways induced by SIAHloss of function as mechanistic, synergistic to kill cancer cells and prevent tumor growth.\nConclusions: RPPA cancer pathway mapping provides invaluable molecular insights into cancer network rewiring in response to SIAH blockade, revealing a major tumor vulnerability. This study supports the design of anti-SIAH-based, anti-EGFR/K-RAS targeted therapies to control and eradicate incurable human cancers.", "source_company": "Eastern Virginia Medical School\nEastern Virginia Medical School at Old Dominion University", "source_org_type": "大学", "row_number": 1075, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "TUSC2 gene therapy", "company": "UT MD Anderson Cancer Center", "org_type": "医院", "target": "未披露", "modality": "gene therapy", "importance_level": "低", "total_score": 46.5, "institution_score": 35, "track_score": 65, "milestone_score": 45, "field_heat_score": 50, "bonus_score": 0, "brief_reason": "TUSC2基因治疗通过抑制MAPK/mTOR通路等机制诱导肿瘤细胞死亡，但靶点为TUSC2本身未明确作为药物直接靶向对象。机构为医院/研究型，preclinical阶段主要聚焦生物标志物筛选，整体开发阶段早期且无头部药企推动，重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4845", "id": "zJ7M_5wBZznHJdnt_W3O", "source_drug_name": "TUSC2 gene therapy", "title": "TROP2 and PTEN are biomarkers of primary resistance to TUSC2 gene therapy in non-small cell lung cancer (NSCLC)", "abstract_text": "Primary resistance to targeted therapies, immunotherapies, and gene therapies in NSCLC continues to be a significant challenge. TUSC2 tumor suppressor gene therapy has shown promising anti-tumor efficacy by overcoming resistance to targeted therapy and enhancing checkpoint blockade immunotherapy, including in a mutant KRAS/LKB1-driven immunotherapy-resistant NSCLC model. TUSC2 protein expression is downregulated or absent in over 80% of NSCLC and 100% of SCLC cases., TUSC2 mediates cancer cell death through several mechanisms: inhibiting MAPK and mTOR signaling pathways, arresting cell growth, inducing programmed cell death, and activating immune responses. We established models primarily resistant to TUSC2 gene therapy to find biomarkers indicative of TUSC2 gene therapy resistance in NSCLC patient-derived xenografts (PDXs), PDX-derived organoids (PDXOs), and cell lines. A panel of 10 NSCLC cell lines screened for TUSC2 sensitivity showed resistance in 50% of the cell lines, as assessed by annexin V staining and colony formation assays. We evaluated TUSC2 sensitivity in 12 NSCLC PDXOs using ATP-based viability assays in 3D culture following TUSC2 or empty vector transfection. While some PDXOs were highly responsive to TUSC2 within 72 hours post-transfection, 50% of PDXOs exhibited primary resistance. We developed TC314AR (Acquired Resistance) PDX tumors and xenograft models (A549, H1299, H23AR) in NSG mice and treated them with TUSC2 gene therapy. 20-30% of tumors in every model showed resistance, with no significant reduction in size compared to the control tumors after treatment. Protein expression profiling using reverse-phase protein array (RPPA) analysis of 500 proteins showed distinct expression signatures, with several candidate biomarkers significantly altered in resistant cell lines and PDXOs. RPPA analysis of residual tumors from both the xenograft and PDX models revealed significant but model-specific alterations in protein expression between responders and non-responders. Comparative analyses across the three models showed low expression of TROP2 and high expression of PTEN as potential biomarkers of primary resistance. Overexpression of TROP2 in H1299 and H460 cells increased TUSC2-induced apoptosis. These findings suggest that TROP2 and PTEN may serve as biomarkers to predict TUSC2 response and guide therapeutic strategies in NSCLC.", "source_company": "UT MD Anderson Cancer Center", "source_org_type": "医院", "row_number": 1096, "target_meta": "not available", "MOA_meta": "基因疗法"}, {"drug_name": "Vps34 inhibitors", "company": "University of Luxembourg", "org_type": "university", "target": "Vps34", "modality": "inhibitor", "importance_level": "中", "total_score": 46.5, "institution_score": 25, "track_score": 75, "milestone_score": 45, "field_heat_score": 65, "bonus_score": 0, "brief_reason": "Vps34抑制剂通过阻断自噬调控增强肿瘤免疫原性，促进免疫细胞募集和CD8+ T细胞杀伤，主要针对MYCN扩增神经母细胞瘤。机构为大学得分较低，但靶点在免疫-自噬交叉领域有一定热度，处于早期preclinical阶段，整体重要性中等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1787", "id": "dp7M_5wBZznHJdnt_W7P", "source_drug_name": "Vps34 inhibitors", "title": "Vps34 inhibition enhances immunogenicity and immune-mediated killing in MYCN-amplified neuroblastoma", "abstract_text": "Neuroblastoma is the most common extracranial solid tumor in children, accounting for approximately 10% of all pediatric cancers and 15% of cancer-related deaths in children under 15 years of age (1). High-risk neuroblastoma, often characterized by MYCN amplification, remains a major therapeutic challenge due to its aggressive behavior and an immunosuppressive tumor microenvironment (TME), which limits the efficacy of current immunotherapies.\nBased on our previous findings (2), we assessed the therapeutic potential of targeting the autophagy regulator class III phosphatidylinositol 3-kinase (PIK3C3, also known as Vps34) to enhance anti-tumor immunity in high-risk neuroblastoma cells. Transcriptomic analysis on murine MYCN-amplified neuroblastoma cells (NHO2A) treated with two distinct Vps34 inhibitors revealed marked upregulation of the pro-inflammatory chemokines CCL5 and CXCL10, both of which are critical for the recruitment of cytotoxic immune cells into the TME. Gene set enrichment analysis (GSEA) further demonstrated significant enrichment of immune activation, cytokine production pathways and biological oxidations, indicating increased tumor immunogenicity upon Vps34 inhibition.\nOur preliminary results further suggest that Vps34 inhibition may trigger features consistent with immunogenic cell death (ICD), as treatment with Vps34 inhibitors significantly increased ATP release. Additional ICD markers are currently being investigated.\nAt the functional levels, in vitro co-culture assays demonstrated that Vps34 inhibition enhances CD8+ T cell-mediated cytotoxicity against MYCN-amplified neuroblastoma cells, confirming the immunostimulatory potential of Vps34 targeting.\nCollectively, our findings underscore the potential of Vps34 inhibition as a promising strategy to render high-risk neuroblastoma cells more susceptible to immune-mediated killing. In vivo studies are currently ongoing to evaluate the therapeutic efficacy of combining Vps34 inhibitors with anti-PD-1 therapy which may pave the way for novel immunotherapeutic approaches for aggressive neuroblastoma.\nReferences\n1. Colon, N. C., Chung, D. H. (2011). Neuroblastoma. Advances in pediatrics.\n2. Noman, M. Z., Parpal, S., Van Moer, K., Xiao, M., Yu, Y., Viklund, J., De Milito, A., Hasmim, M., Andersson, M., Amaravadi, R. K., Martinsson, J., Berchem, G., Janji, B. (2020). Inhibition of Vps34 reprograms cold into hot inflamed tumors and improves anti-PD-1_PD-L1 immunotherapy. Science advances.", "source_company": "University of Luxembourg", "source_org_type": "大学", "row_number": 1202, "target_meta": "PIK3C3", "MOA_meta": "抑制剂"}, {"drug_name": "ANC", "company": "COMPO SmartC", "org_type": "公司", "target": "HER2", "modality": "other", "importance_level": "低", "total_score": 46, "institution_score": 40, "track_score": 60, "milestone_score": 40, "field_heat_score": 50, "bonus_score": 0, "brief_reason": "ANC为曲妥珠单抗功能化的纳米颗粒递送多西他赛，主要靶向HER2阳性乳腺癌，展示免疫调节趋势如降低Treg和增加肿瘤内激活NK细胞，但仅为preclinical小鼠模型初步趋势，无明确新机制或突破数据。机构为非知名公司，赛道为纳米递送+免疫调节但非热门modality，开发阶段早期导致总分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9479", "id": "81XM_5wBX1NQZOEH-LK6", "source_drug_name": "ANC", "title": "Quantitative and functional immune reprogramming induced by a nanomedicine in breast cancer model", "abstract_text": "Nanoparticles (NPs) are emerging as a promising strategy in oncology, offering optimised drug delivery and the potential to modulate immune responses. In this study, we developed an innovative nanoparticle encapsulating docetaxel and functionalised with trastuzumab for precise targeting of HER2-positive tumours (called ANC for Antibody Nanoparticle Conjugate). Immunomodulatory effects were performed in C57BL/6 mice administered free docetaxel (1.6 mg-kg-¹) and trastuzumab (135 ng-kg-¹) by intraperitoneal injection (n = 29) or ANC (nanoparticles at the same docetaxel and trastuzumab doses as the free drugs, n = 40). Immune profiling was performed in blood (J0-J21) and tumor tissue (J21) to evaluate quantitative and functional changes in major lymphoid and myeloid subsets involved in antitumor immunity. Flow cytometric analyses included B cells, T cells (CD4⁺, CD8⁺), activated T-cell subsets, NK cells, regulatory T cells (Treg), myeloid-derived suppressor cells (MDSC), and regulatory B cells (Breg). In blood, no significant differences were observed between groups for B cells, NK cells, CD4⁺ or CD8⁺ T cells, or their activated subsets. A trend toward reduced Treg frequencies was detected in the ANC group compared with controls (p = 0.053), suggesting early systemic modulation of immunosuppressive activity. MDSC levels remained unchanged across all groups. In tumors, global B-cell levels were comparable between groups, but ANC-treated mice showed an increased proportion of Breg, indicating a potential local immunosuppression. NK-cell infiltration and activation tended to be higher in the ANC group (p ≈ 0.08), suggesting localized immune stimulation. No differences were detected for CD4⁺ T cells, whereas a reduction in CD8⁺ T-cell frequency was observed in ANC-treated tumors. Treg levels also showed a decreasing trend (p = 0.07), consistent with a partial reduction in immunoregulatory pressure within the tumor microenvironment. MDSC levels did not differ significantly between conditions. ANC formulation exhibited subtle yet biologically relevant immunomodulatory trends, including reduced Treg frequencies and increased activated NK cells within the tumor, potentially favoring antitumor responses. Conversely, the elevated Breg population in ANC-treated tumors may counterbalance these effects by promoting local immunosuppression. These findings suggest that ANC may fine-tune the tumor immune landscape without inducing major systemic alterations. Further investigation with extended cohorts and functional assays will be required to confirm these trends and clarify their implications for therapeutic efficacy.", "source_company": "COMPO SmartC", "source_org_type": "公司", "row_number": 227, "target_meta": "HER2", "MOA_meta": "其他"}, {"drug_name": "anti-HER2 antibody-(IL-12)", "company": "UC San Diego", "org_type": "大学", "target": "HER2", "modality": "other", "importance_level": "低", "total_score": 46, "institution_score": 35, "track_score": 65, "milestone_score": 40, "field_heat_score": 55, "bonus_score": 3, "brief_reason": "药物为HER2抗体融合IL-12的免疫细胞因子融合蛋白，机制结合HER2靶向与IL-12免疫激活；在大学机构开展的动物模型联合植物病毒免疫治疗研究，preclinical阶段协同效应初步显示，但缺乏临床转化迹象及头部机构推进，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5321", "id": "CVXM_5wBX1NQZOEH-LS6", "source_drug_name": "anti-HER2 antibody-(IL-12)", "title": "Cocktail immunotherapy: Plant virus immunomodulator, HER2 antibody, and co-delivered IL-12 cytokine for the treatment of HER2+ cancer", "abstract_text": "Cowpea Mosaic Virus (CPMV) is a plant virus which infects legumes such as cowpea plants. It has been used as a powerful intratumoral immunotherapy in murine cancer models and canine veterinary clinical trials. CPMV is a multi- Toll-Like Receptor (TLR) agonist which induces a strong anti-tumor immune response both locally and systemically. While highly potent as a monotherapy, the most robust immunotherapy approaches are those which target cancer through multiple axes. In the present work, we tested the combination of intratumoral immunotherapy using CPMV with human epidermal growth factor receptor 2 (HER2) monoclonal antibody (mAb) therapy targeting HER2+ tumors. More specifically, we combined CPMV with an anti-HER2 mAb or anti-HER2 antibody-(IL-12) fusion protein (anti-HER2 antibody-(IL-12))—an anti-HER2 antibody genetically fused to the cytokine IL-12. Amplification of HER2 is known to occur in several cancers and is associated with poor prognosis as well as cancer recurrence. Mice with HER2+ tumors from colorectal cancer cell lines (MC38-HER2+ and CT26-HER2+) were treated with CPMV and HER2 mAb or anti-HER2 antibody-(IL-12). Tumor volume and overall survival were measured over the course of 8 weeks. While animals were refractory to HER2 mAb therapy alone, reduced tumor growth and increased survival was achieved using CPMV and the combination therapies- with the combination therapies outperforming CPMV therapy alone. These results indicate that CPMV can synergize with targeted antibody therapies for greater anti-tumor efficacy.\nThis work was funded in part through NIH grants R01-CA274640 and R01-CA253615-02S1, NIH training grant T32-CA121938, the American Cancer Society Extramural Discovery Science (EDS) Accelerator Award EDS-24-1330440-01-EDS, and the American Cancer Society - F.M. Kirby Foundation Inc. - Mission Boost Grant MBGI-23-1030244-01-MBG.\nThe authors declare the following competing financial interests: Dr. Steinmetz is a co-founder and CEO of and has equity in PlantiosX Inc. Dr. Steinmetz is a co-founder of and has equity in Mosaic Immunoengineering, Inc. Dr. Steinmetz is a cofounder and manager of Pokometz Scientific LLC, under which she is a paid consultant to Ring Therapeutics, Inc. The other authors declare no potential conflicts of interest.", "source_company": "UC San Diego", "source_org_type": "大学", "row_number": 837, "target_meta": "HER2", "MOA_meta": "其他"}, {"drug_name": "miR-6883 lipid nanoparticles", "company": "Brown University", "org_type": "大学", "target": "未披露", "modality": "mRNA", "importance_level": "中", "total_score": 46, "institution_score": 25, "track_score": 75, "milestone_score": 45, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "miR-6883脂质纳米颗粒通过沉默CDK4/6实现抗增殖和抗缺氧作用，但靶点未直接明确披露。大学机构+preclinical阶段组合协同数据导致综合评分中等，热门小核酸赛道和抗缺氧机制提供一定吸引力。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4437", "id": "R57M_5wBZznHJdnt_W7P", "source_drug_name": "miR-6883 lipid nanoparticles", "title": "Combination of CDK4/6 inhibitory and anti-hypoxia miRNA-6883 lipid nanoparticles with ferroptosis inducers or MEK inhibitors in preclinical breast and colorectal cancer models", "abstract_text": "Introduction\nMicroRNA 6883-5p (miR-6883) inhibits cancer proliferation and hypoxia signaling by silencing the cyclin-dependent kinases CDK4/6, inducing downstream degradation of Hypoxia-Inducible Factor 1α (HIF1α). Prior work demonstrated that CDK4/6 inhibition (CDK4/6i) induces HIF1α degradation through a VHL-independent mechanism via the E3 ubiquitin ligase SMURF2. Notably, several preclinical studies have reported synergy between CDK4/6i and MEK inhibition (MEKi). Others have reported that CDK4/6i sensitizes cancer cells to ferroptosis inducing agents, though this observation is not unequivocally supported and may be context-dependent. Here, we investigate combinations of miR-6883 lipid nanoparticles (LNPs) with MEKi or ferroptosis inducers using in vitro assays and in vivo murine xenograft models.\nMethods\nA hypoxia response element (HRE)-driven reporter (Addgene #118706) was transduced into HCT116 colorectal carcinoma and SK-BR-3 HER2+ breast cancer (BC) cells. For in vivo experiments, 2 million HCT116-HRE cells were injected subcutaneously into nude mice and tumors ≥150mm3 were treated with 0, 1, or 10µg LNP-encapsulated miRNA. For viability assays, 4,000 cells/well were plated and allowed to adhere overnight. 48-72h after treatment, viability was assessed by CellTiter-Glo®. In vitro hypoxia experiments were conducted in a 0.5% O2 hypoxia workstation.\nResults\nAs a single agent, miR-6883 LNPs significantly attenuated HIF signal in the HCT116-HRE xenograft model, with a 94.3% reduction in luminescence observed 3 days post-treatment with 1µg miR-6883 compared to baseline. Ki67 was significantly reduced with a 10µg dose, supporting the antiproliferative activity of miR-6883. In vitro, the SK-BR-3-HRE model demonstrated a significant reduction in HIF activity with miR-6883 treatment under 0.5% O2, suggesting that the anti-hypoxia effect of miR-6883 extends to BC. In vitro viability assays were conducted in HCT116 (colorectal), SK-BR-3 (HER2+), MCF-7 (ER+), MDA-MB-231 (triple-negative), and MDA-MB-468 (triple-negative). Combination of small-molecule CDK4/6i and ferroptosis inducers (RSL3 or erastin) or MEKi (trametinib) revealed largely positive synergy scores. Accordingly, miR-6883 LNPs sensitized cells to doses of RSL3, erastin, or trametinib that were ineffective as monotherapies.\nConclusions\nOur data support the anti-hypoxia and antiproliferative activity of miR-6883, and provide a basis for combination therapies with ferroptosis inducers or MEKi. Future experiments will employ BC xenografts and assess long-term tumor growth inhibition of combination therapies.", "source_company": "Brown University", "source_org_type": "大学", "row_number": 1175, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "LNP-TRAIL", "company": "Universidade Federal de Minas Gerais (UFMG)", "org_type": "大学", "target": "TRAIL", "modality": "mRNA", "importance_level": "低", "total_score": 45.8, "institution_score": 25, "track_score": 75, "milestone_score": 45, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "LNP-TRAIL为脂质纳米粒递送TRAIL mRNA，与CLDN6 CAR-T联用增强实体瘤疗效；大学机构+早期动物模型研究导致整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5593", "id": "Z1XM_5wBX1NQZOEH-LK6", "source_drug_name": "LNP-TRAIL", "title": "CAR T cells engineered via mRNA exhibit enhanced targeting of colorectal cancer", "abstract_text": "Chimeric antigen receptor (CAR) T-cell therapy has revolutionized the treatment of hematologic malignancies, achieving unprecedented remission rates in patients with refractory leukemias, lymphomas, and multiple myeloma. However, translating CAR T therapy to solid tumors remains challenging due to intratumoral heterogeneity, an immunosuppressive tumor microenvironment, and limited tumor-specific antigens. In this work, we employed a lipid nanoparticle (LNP)-based mRNA delivery platform to transiently generate CAR T cells targeting Claudin-6 (CLDN6), an oncofetal tight junction protein aberrantly expressed in multiple tumors, including colorectal cancers. To enhance antitumor efficacy, we combined CAR T cell therapy with localized LNP-mediated delivery of TRAIL mRNA (LNP-TRAIL). We evaluated this dual approach in a subcutaneous xenograft model using Colo 205-GFP+Luc+ human colorectal cancer cells in NSG mice. Tumor growth was monitored by quantitative bioluminescence imaging and caliper-based tumor volume measurements. Tumor-infiltrating lymphocytes (TILs) were profiled for activation markers, proliferation, cytotoxic mediators (IFN-y, Granzyme B), and immune checkpoint expression (PD-1, CTLA-4) to assess T cell exhaustion. To examine translational potential, we performed ex vivo assays using freshly resected human colorectal tumor fragments treated with CAR-T cells. The resulting CAR-T cells generated via LNP-mRNA exhibited robust activation, proliferation, and cytotoxicity against CLDN6+ colorectal cancer cells both in vitro and in vivo. Combined CAR-T and intratumoral LNP-TRAIL therapy significantly reduced tumor burden, enhanced T cell infiltration and effector function, and reversed markers of T cell exhaustion. Ex vivo co-culture with primary human tumor samples further confirmed the improved cytotoxic and immunostimulatory effects of the dual strategy. These results establish a modular mRNA nanoplatform that integrates transient CAR expression with LNP-TRAIL delivery to overcome major barriers to CAR-T efficacy in solid tumors, highlighting its translational potential for CLDN6+ malignancies.", "source_company": "Universidade Federal de Minas Gerais (UFMG)", "source_org_type": "大学", "row_number": 552, "target_meta": "TNFSF10", "MOA_meta": "其他"}, {"drug_name": "itaconate", "company": "Huazhong University of Science and Technology", "org_type": "大学", "target": "KDM5B", "modality": "other", "importance_level": "低", "total_score": 45.8, "institution_score": 25, "track_score": 75, "milestone_score": 35, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "Itaconate通过直接结合并抑制KDM5B（α-KG拮抗作用）并重定向葡萄糖通量促进记忆CD8+ T细胞分化，机制新颖但仅为内源性代谢物。大学机构+纯preclinical机制研究导致总体分较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5284", "id": "bVXM_5wBX1NQZOEH-LK6", "source_drug_name": "itaconate", "title": "Itaconate promotes memory CD8+ T cell development by epigenetic modification and glucose flux redirection in viral infection and cancer", "abstract_text": "Background: Coordinated metabolic alterations and epigenetic remodeling are known to critically influence T cell fate decisions and functional states. However, the specific extrinsic metabolic signals that guide CD8+ T cell memory differentiation remain to be fully elucidated.\nMethods: Naïve CD45.1⁺ OT-I CD8⁺ T cells were adoptively transferred into Listeria monocytogenes-infected CD45.2 mice to track in vivo differentiation trajectories. Tumor-infiltrating CD8⁺ T cells were analyzed by single-cell RNA sequencing to delineate T cell subclusters. Mechanistically, we profiled global chromatin accessibility of CD8⁺ T cells under itaconate treatment using ATAC-seq, revealing its epigenetic remodeling effects. Through a combination of surface plasmon resonance (SPR) and complementary biochemical assays, we demonstrated that itaconate directly binds to lysine demethylase 5B (KDM5B) and functionally antagonizes α-ketoglutarate (α-KG). Furthermore, metabolic flux analyses, along with direct measurements of NADPH and GSH levels, confirmed that itaconate drives metabolic reprogramming in CD8⁺ T cells to sustain redox balance and memory differentiation capacity.\nResults: We found that itaconate, induced during immune responses, is a critical promoter of memory T cell (TM) differentiation. Mechanistically, itaconate directly binds to KDM5B and acts as an α-KG antagonist, competitively inhibiting KDM5B-dependent demethylation of H3K4me3. This inhibition leads to increased chromatin accessibility at genes essential for TM cell differentiation. Furthermore, itaconate redirects glucose flux from glycolysis to the PPP, thereby ensuring high levels of NADPH and glutathione in TM cells to alleviate oxidative stress.\nConclusions: Our results identify itaconate as a key immunometabolic regulator that promotes durable immune memory in viral infections and cancer by concurrently modulating epigenetic programming and metabolic fitness. This machinery presents a potential therapeutic target to enhance the stem-like phenotype and persistence of CAR T cells.", "source_company": "Huazhong University of Science and Technology", "source_org_type": "大学", "row_number": 556, "target_meta": "KDM5B", "MOA_meta": "其他"}, {"drug_name": "PARP inhibitors", "company": "Edward Via College of Osteopathic Medicine–Carolinas Campus", "org_type": "大学", "target": "PARP", "modality": "inhibitor", "importance_level": "低", "total_score": 45.8, "institution_score": 25, "track_score": 75, "milestone_score": 35, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "PARP抑制剂针对DNA损伤修复机制，在多发性骨髓瘤中通过诱导BRCAness与β-catenin抑制联用克服化疗耐药。机构为大学非商业实体、仅细胞和类器官水平研究，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4005", "id": "klXM_5wBX1NQZOEH-LK6", "source_drug_name": "PARP inhibitors", "title": "Exploiting Wnt-induced DNA damage repair vulnerability with PARP inhibitors to overcome chemoresistance in multiple myeloma", "abstract_text": "Multiple Myeloma (MM) is a plasma cell malignancy characterized by the clonal proliferation of malignant plasma cells in the bone marrow, leading to the excessive production of monoclonal immunoglobulin. This proliferation and the subsequent interaction with the bone microenvironment result in significant end-organ damage, classically represented by the CRAB criteria: Calcium elevation (hypercalcemia), Renal failure, Anemia, and Bone lesions (lytic lesions, pain, and fractures). It is a highly aggressive and lethal cancer, notorious for high recurrence rates and a lack of effective targeted therapies. While PARP inhibitors (PARPi) are potent agents, their clinical benefit is narrowly restricted to the small patient subset harboring BRCA mutations. We present a strategy to expand PARPi efficacy in MM. We discovered that the Wnt signaling transcription factor, beta-catenin, controls the expression of the critical Fanconi Anemia DNA repair protein, FANCD2 and cohesion protein CTCF in MM cells. Crucially, inhibiting beta-catenin in initially resistant MM cells (those that are homologous recombination, or HR, proficient) induces a BRCA-like deficiency known as BRCAness and severe replication stress. This combination—beta-catenin inhibition paired with PARPi—shows enhanced DNA damage, striking synergistic lethality in cell models, and powerful anticancer activity in organoid models. This dual-targeting approach offers a novel and effective strategy to overcome resistance in MM.", "source_company": "Edward Via College of Osteopathic Medicine–Carolinas Campus", "source_org_type": "大学", "row_number": 581, "target_meta": "PARP", "MOA_meta": "抑制剂"}, {"drug_name": "gold-coated solid lipid nanomaterial", "company": "Tata Memorial Centre", "org_type": "医院", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 45.8, "institution_score": 35, "track_score": 45, "milestone_score": 55, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "Au-SLN为光热治疗材料，未明确特定靶点，属于物理作用机制而非靶向药物；Tata Memorial Centre为知名癌症医院但非商业药企，赛道为光热治疗+CTC监测在preclinical阶段，整体开发热度和商业化潜力有限。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6263", "id": "bFXM_5wBX1NQZOEH-LS6", "source_drug_name": "gold-coated solid lipid nanomaterial", "title": "Development of a bioluminescence imaging-guided CTC liquid biopsy procedure to identify the optimal time window for achieving superior photothermal therapy efficacy", "abstract_text": "Global cancer burden represents one of the most significant challenges in public health. Notable concern for the mainframe therapeutic procedures is the high incidence of relapsed disease among majority patients availing those. This problem is frequently attributed to the evolving state of cancer cell dissemination, where circulating tumor cells (CTCs) begin to appear in the blood circulation. However, due to CTC enrichment requirement, high-volume blood withdrawal repeatedly during initial or follow up diagnosis, raises an ethical concern, and therefore CTC determination not integral in practice. Given the sparse nature of CTC applications in preclinical experiments using mouse model, where the total blood volume is limited to only 1.5 ml/mouse, in this study we challenged this dogma, and established a luminescence-based CTC detection method using preclinical mouse tumor models. The optimized liquid biopsy process using bioluminescence imaging-guidance allowed detection of up to two cells from as low as 100μl blood volumes, allowing us to follow the CTC surge dynamics from a very low blood volume. We examined both CTC dynamics and metastatic potential in mice bearing highly aggressive 4T1-FLuc2 and a relatively indolent ZR-75-1-Nanoluc orthotopic breast cancer models. To test the case, we further used our well-standardized photothermal therapy (PTT) procedure using gold-coated solid lipid nanomaterial (Au-SLN) and demonstrate that when PTT is performed in a temporally optimized window, the therapy application does not induce a detectable CTC flux (p< 0.05), nor distant spread of malignant tumors in the vital organs, both in highly aggressive and less aggressive breast cancer models. Imaging signal from CTC was confirmed further by molecular biomarker and transcriptomic characterization, revealing a close association of EpCAM positive CTCs with tumor aggressiveness and their metastatic propensity. These effects essentially improve mice longevity and relapse-free survival of the mice. Our findings highlight that Au-SLN mediated PTT could provide a relapse-free efficacious treatment, when performed before viable CTCs are released and underscore the importance of integrating a sensitive liquid biopsy method for monitoring metastatic risk and chance of disease relapse.", "source_company": "Tata Memorial Centre", "source_org_type": "医院", "row_number": 908, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "Antimycin A", "company": "Institut Gustave Roussy", "org_type": "医院", "target": "线粒体呼吸链复合物III", "modality": "inhibitor", "importance_level": "低", "total_score": 45.5, "institution_score": 35, "track_score": 60, "milestone_score": 45, "field_heat_score": 50, "bonus_score": 0, "brief_reason": "Antimycin A为经典线粒体复合物III抑制剂，在SWI/SNF缺陷癌模型中显示选择性细胞毒性，提示合成致死机制。机构为医院/学术型，非商业药企，处于工具化合物验证阶段而非药物开发，整体重要性有限。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/7871", "id": "cFXM_5wBX1NQZOEH-LG5", "source_drug_name": "Antimycin A", "title": "Integrated multiomic profiling reveals SWI-SNF subunit-specific pathway alterations and targetable vulnerabilities", "abstract_text": "Background: Mutations in subunits of SWI/SNF chromatin remodeling complex frequently occur in cancer and no targeted therapy is currently available for this patient population. To systematically characterize novel targetable vulnerabilities in SWI/SNF-deficient cancers, we integrated multiomics profiling and drug screening of tumor cell lines with publicly available molecular profiling and CRISPR screen, using newly developed bioinformatic methodologies.\nMethods: We generated in-house transcriptome and proteome profiling with high-throughput drug screening on a panel of isogenic HAP1 cell lines knocked-out (KO) for genes encoding SWI/SNF subunits or other chromatin remodelers. We further acquired publicly available molecular profiling and CRISPR-screen datasets from the TCGA and DepMap projects, respectively, and integrated all results. Gene set enrichment analyses were performed using an optimized pipeline based on (i) a pruned version of the Reactome pathway database, (ii) combining ROntoTools and GSEA algorithms, which scored as top performant strategy. Synthetic lethal interactions (SLi) from the DepMap CRISPR screening were identified using a new benchmarked SLi algorithm, based on expression levels of genes on interest, to consider functional deficiencies.\nResults: Metabolism of proteins, which had not previously been linked to SWI/SNF, was the most frequently dysregulated pathway category both in HAP1 SWI/SNF-KO mutant cell lines and in the DepMap analysis comparing models with low and high SWI/SNF subunit expression; it was the third most dysregulated in SWI/SNF-defective TCGA patient tumors (after Signal transduction and Immune system, potentially due to the presence of an immune microenvironment). High-throughput drug screen identified multiple pharmacological vulnerabilities, including inhibitors of the histone acetyltransferase CBP/EP300 or mitochondrial respiration, which were selectively cytotoxic in SWI/SNF-defective models. Our new SLi algorithm, also independently identified genetic synthetic lethality between SWI/SNF defects and EP300 or mitochondrial respiration genes. These orthogonal genetic and chemical vulnerabilities were revalidated experimentally in histotype-relevant SMARCA4-isogenic models, using two highly selective EP300 inhibitors and the mitochondrial respiratory chain complex III inhibitor Antimycin A.\nConclusion: Integrating multi-omics profiling with high-throughput drug- and genetic- screening, respectively analyzed using an optimized enrichment pipeline and a newly developed SLi algorithm, enabled the identification of actionable genetic dependencies in SWI/SNF-defective cancers. These predicted synthetic lethal interactions were experimentally validated in relevant models, supporting their clinical relevance.\nJBS and CA contributed equally. SPV and AB contributed equally.", "source_company": "Institut Gustave Roussy", "source_org_type": "医院", "row_number": 16, "target_meta": "not available", "MOA_meta": "抑制剂"}, {"drug_name": "CDK4/6 inhibitors", "company": "National Yang Ming Chiao Tung University", "org_type": "大学", "target": "未披露", "modality": "inhibitor", "importance_level": "低", "total_score": 45.5, "institution_score": 25, "track_score": 75, "milestone_score": 35, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "摘要聚焦CDK4/6抑制剂耐药机制研究（YWHAZ/YWHAB介导蛋白酶体功能），未披露新型药物靶点或modality；大学机构基础研究性质，缺乏药物开发里程碑，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11131", "id": "GVXM_5wBX1NQZOEH-LK6", "source_drug_name": "CDK4/6 inhibitors", "title": "Proximity labeling and thermal profiling proteomic analysis unveil mechanistic role of YWHAZ and YWHAB in CDK4/6 inhibitor resistance", "abstract_text": "CDK4/6 inhibitors are currently standard of care in both early and metastatic hormone positive breast cancer. With the expanded use of CDK4/6 inhibitors in early breast cancer, identifying and addressing resistance mechanisms become increasingly important for improving patient outcome. In our prior work, using proximity labeling approaches, we identified the YWHAB/YWHAZ complex (both members of the 14-3-3 family) as important mediators for CDK4/6 inhibitors resistance. Genetic silencing of YWHAB sensitized resistant hormone positive breast cancer cells towards CDK4/6 inhibitors. We further demonstrated that YWHAB-YWHAZ existed as a dimer and suppressed proteosomal function for CDK6 degradation, leading to CDK4/6 inhibitor resistance. To elucidate the interactome of YWHAZ, and to probe for proteosomal roles in CDK4/6 inhibitor resistance, we performed Thermal Proximity Co-aggregation (TPCA) proteomics on cells with/without YWHAZ silencing. TPCA analysis identified proteins involved in proteosomal processing and confirmed a role of YWHAZ in mediating proteosomal degradation. Further functional studies validate novel mechanisms for CDK4/6 inhibitors. Our findings were correlated with TCGA and other public cohorts to demonstrate a prognostic and predictive role of YWHAZ in CDK4/6 inhibitors. In summary, our findings indicate a role for proteosomal selectivity that mediates CDK4/6 inhibitor resistance and could serve as future therapeutic targets for hormone positive breast cancer.", "source_company": "National Yang Ming Chiao Tung University", "source_org_type": "大学", "row_number": 23, "target_meta": "not available", "MOA_meta": "抑制剂"}, {"drug_name": "magnetic embolization beads", "company": "University of Illinois at Chicago", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 45.5, "institution_score": 30, "track_score": 45, "milestone_score": 65, "field_heat_score": 50, "bonus_score": 3, "brief_reason": "该产品为磁性栓塞微球，属物理定位增强型栓塞材料而非针对特定靶点的药物，无明确药物靶点。大学机构+preclinical概念验证阶段+非热门药物赛道导致整体重要性较低，但磁导航增强栓塞有一定技术创新亮点。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8591", "id": "dVXM_5wBX1NQZOEH-LK6", "source_drug_name": "magnetic embolization beads", "title": "Development and preclinical validation of magnetomotive embolization for enhanced targeting of hepatocellular carcinoma", "abstract_text": "Background: Hepatocellular carcinoma (HCC) is the most common type of primary liver cancer and remains a leading cause of cancer mortality worldwide. Catheter-directed transarterial embolization (with or without chemotherapy) is the standard treatment for intermediate-stage HCC, but its survival benefit remains modest, reflecting limitations such as incomplete tumor embolization. To address these limitations, we aimed to develop an embolization approach that improves intratumoral bead localization and tumor embolization through biocompatible magnetic embolization beads and magnetic field guidance.\nMethods: A dual-cylinder NdFeB magnet system was engineered to generate focused magnetic fields up to 25 mT at 7.5 cm from the magnet surface, creating a stable magnetic trap. Polycaprolactone-based magnetic embolization beads (40-60 µm) incorporating ~30 nm Fe3O4 iron oxide nanoparticles were synthesized using emulsion polymerization and characterized for morphology, uniformity, and magnetization. Magnet-guided bead delivery was assessed in 3D-printed vascular tumor phantoms and validated in vivo using the rabbit VX2 liver tumor model. Tumor-bearing rabbits (n=12) underwent transarterial embolization and were randomized into magnet-guided (5 Hz alternating rotation, 15 minutes) or control groups (n=6 each).\nResults: Microscopic analysis confirmed uniform spherical bead morphology with a narrow size distribution, while SQUID magnetometry demonstrated ferrimagnetic behavior of Fe3O4 nanoparticle cores (magnetization 63.6 emu/g, coercivity 20 Oe at 800 kA/m), confirming strong magnetic responsiveness, and supporting MR-safety. Powder X-ray diffractometry confirmed Fe3O4 with no anomalous peaks suggesting the presence of undesirable iron oxide species. In tumor phantoms, the magnet system successfully concentrated magnetic beads within targeted regions at preclinical relevant distances, achieving reproducible spatial control and contrasting with heterogeneous dispersion in controls. In vivo, transarterial delivery was technically feasible and well tolerated in all tumor-bearing rabbits with no acute complications. Histopathologic analysis demonstrated concentration of the magnetic beads in tumor vasculature in magnet-assisted animals. No device-related toxicity was observed.\nConclusion: This study establishes proof-of-concept for magnetomotive embolization as a novel and feasible locoregional therapy for HCC. The findings demonstrate technical feasibility, procedural safety, and effective intratumoral bead localization in both phantom and preclinical animal models. Building on these results, future work will focus on integrating robotic magnetic field control for dynamic targeting and performing quantitative efficacy and safety studies in large-animal models to advance this technology toward clinical translation.", "source_company": "University of Illinois at Chicago", "source_org_type": "大学", "row_number": 38, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "anti-CD3xCD19 BiTE", "company": "The Jackson Laboratory", "org_type": "研究机构", "target": "CD3/CD19", "modality": "bispecific antibody", "importance_level": "低", "total_score": 45.5, "institution_score": 35, "track_score": 75, "milestone_score": 25, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "anti-CD3xCD19 BiTE为经典CD3×肿瘤靶点双抗，属于BiTE类双抗热门赛道，但The Jackson Laboratory作为研究机构而非药企，研发推动力有限。摘要仅用于模型验证BiTE疗效与CRS，无药物自身新机制或开发进展，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5122", "id": "-VXM_5wBX1NQZOEH-LO6", "source_drug_name": "anti-CD3xCD19 BiTE", "title": "A novel NSG-SGM3xIL15xDKO-based PBMC humanized mouse model to evaluate efficacy and cytokine release of immunotherapies", "abstract_text": "We have observed better engraftment of human peripheral blood mononuclear cells (PBMCs) in NSG-SGM3xIL15xDKO (SDKO) mice compared to NSG-MHC I/II DKO (DKO) mice without irradiation. Irradiation is a way to stimulate immune responses. We examined how irradiation affects human PBMC engraftment in SDKO mice and compared engraftment in irradiated SDKO and DKO mice with and without cancer cells. Efficacy and toxicity of anti-CD3xCD19 BiTE were also tested in Raji model of irradiated SDKO and DKO. Methods SDKO and DKO mice were intravenously injected with PBMCs with/without irradiation. Retro-orbital (RO) bleeding was performed to check engraftment with flow cytometry. SDKO and DKO mice were also injected with cancer cells prior to intravenous injection of PBMCs after irradiation. RO blood and spleen were collected to check engraftment of various cell types. Raji-luc-bearing SKO and DKO mice with irradiation were treated with PBS or anti-CD3xCD19 BiTE. Xenogen was performed to measure tumor burdens, and plasma was collected to measure cytokine levels with Luminex assay. Results  Irradiation accelerated human CD45 (hCD45) cells engraftment in SDKO mice. On day 10 or 14, SDKO mice after irradiation showed 3 folds of hCD45 engraftment compared to SDKO mice that didn’t receive irradiation. CD3+ T cells, CD19+ B cells and CD56+ nature killer (NK) cells were engrafted at 2-6 fold higher in irradiated SDKO mice at early timepoints compared to non-irradiated mice. Irradiation significantly improved B cells and NK cells in SDKO mice compared to no irradiation. PBMCs were engrafted at higher levels in SDKO compared to DKO after irradiation. It included CD4+T cells, CD8+T cells, B cells and NK cells in the blood and spleen. On day 9, T cells, B cells, NK cells, dendritic cells (DC) and macrophages in the spleen were 2-10 fold higher in irradiated SDKO compared to DKO. B cell lymphoma Raji cells stimulated PBMCs to engraft after irradiation, including T cells, NKs and macrophages in the spleen. More importantly, SDKO was engrafted at significantly higher cell counts compared to DKO with Raji cells stimulation, including DCs and macrophages. Lastly, we found SDKO supported Raji growth with higher tumor burden on three days after implantation compared to DKO. At the same time, Raji-bearing SDKO responded to anti-CD3xCD19 BiTE faster than DKO, making SDKO a more sensitive model to test BiTE efficacy than DKO. In addition, cytokines production after anti-CD3xCD19 BiTE was much higher in SDKO than DKO in the Raji model. Conclusion Irradiation not only expediates engraftment of human PBMCs in SDKO mice. Various cell types, including B cells, NK cells, DCs and macrophages, plus T cells are engrafted at higher cell counts in SDKO than DKO with/without cancer cells stimulation with irradiation. In addition, SDKO implanted with cancer cells is a more sensitive platform than DKO to test drug efficacy and toxicity.", "source_company": "The Jackson Laboratory", "source_org_type": "研究机构", "row_number": 66, "target_meta": "CD3,CD19", "MOA_meta": "双特异性抗体"}, {"drug_name": "soluble VEGFR3 antagonist", "company": "University of Illinois Chicago", "org_type": "大学", "target": "VEGFR3", "modality": "other", "importance_level": "低", "total_score": 45.5, "institution_score": 30, "track_score": 65, "milestone_score": 50, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "药物为soluble VEGFR3 antagonist，针对VEGFR3以阻断JAG1促进的淋巴结转移机制，在乳腺癌前临床模型中显示抑制淋巴结转移效果。机构为大学非商业研发，赛道为淋巴血管生成相关靶向但非热门modality，开发阶段为preclinical动物模型验证，无突出临床里程碑或新机制亮点导致总分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/2771", "id": "Xp7M_5wBZznHJdnt_W7P", "source_drug_name": "soluble VEGFR3 antagonist", "title": "Tumor cell JAG1 promotes lymph node metastasis and predicts recurrence in lymph node positive breast cancer patients", "abstract_text": "Lymph node metastasis is a “canary in the coal mine” in breast cancer, acting as a distinct prognostic indicator of aggressive disease. In preclinical models, invasion of tumor cells into lymphatics and lymph nodes is promoted by LECs that are active participants in the promotion of tumor cell invasion. It remains unclear how breast tumors interact with LEC cell signaling pathways to transverse lymphatic endothelium. Better understanding of specific and clinically actionable mechanisms that tumor cells use to promote lymphogenous metastasis are needed to reduce disease progression to distant organs. Expression of the Notch ligand JAG1 has long been associated with poor prognosis in patients, and JAG1 has been established to have critical roles in lymphatic specification and development. Using mouse models, we report that JAG1 expression in tumor cells actively promotes lymph node metastasis. JAG1 expression in tumor cells promotes progression through multiple stages of the lymphogenous metastatic cascade, including lymphovascular invasion into peritumoral lymphatic vessels, entry to mammary lymphatic collecting ducts, invasion into the subcapsular sinus of the lymph node, and overt nodal metastasis. To understand the underlying mechanisms of JAG1-driven metastasis, we determined that exposure of LECs to JAG1, either by JAG1-expressing tumor cells or tethered exogenous ligand, disrupted lymphatic barrier integrity and increased tumor cell migration across LEC monolayers in vitro. JAG1-stimulated transendothelial tumor migration could be suppressed with a Notch4-inhibiting antibody, but was not affected by treatment with a canonical Notch inhibitor. We demonstrated that JAG1 expression in tumor cells promotes VEGFR3 activity in LECs. JAG1-dependent lymph node metastasis can be suppressed with two distinct soluble VEGFR3 antagonists in vivo. In human synchronous breast and lymph node samples from node positive patients, we demonstrate that tumor cells in the lymph node are enriched in JAG1 compared to the primary tumor. Enrichment of JAG1 in lymph nodes was clinically meaningful, as JAG1 levels in the node, but not the primary tumor, predicted disease recurrence post-lumpectomy, which suggests that molecular workup of sentinel lymph nodes may be informative in lymph node positive patients. These data provide a novel mechanism by which tumor cells regulate cell behaviors in nearby lymphatic endothelium to promote invasion and lymphogenous metastasis.", "source_company": "University of Illinois Chicago", "source_org_type": "大学", "row_number": 100, "target_meta": "VEGFR3", "MOA_meta": "其他"}, {"drug_name": "BCCA7693", "company": "BC Cancer Research Institute", "org_type": "研究机构", "target": "DNA-PK", "modality": "inhibitor", "importance_level": "低", "total_score": 45.5, "institution_score": 35, "track_score": 65, "milestone_score": 40, "field_heat_score": 50, "bonus_score": 0, "brief_reason": "BCCA7693为新型口服DNA-PK抑制剂，可延缓靶向治疗获得性耐药的发生，但靶点DNA-PK在肿瘤治疗中非最热门，临床开发价值中等。机构为研究机构而非商业公司，得分较低，摘要被禁导致阶段信息不足，整体重要性偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11480", "id": "wVXM_5wBX1NQZOEH-LG6", "source_drug_name": "BCCA7693", "title": "BCCA7693 - A novel, orally bioavailable DNA-PK inhibitor demonstrates efficacy with targeted therapeutics by inhibiting the development of acquired resistance", "abstract_text": "Abstract is embargoed at this time.", "source_company": "BC Cancer Research Institute", "source_org_type": "研究机构", "row_number": 199, "target_meta": "DNA-PK", "MOA_meta": "抑制剂"}, {"drug_name": "CCR7-blocking antibody", "company": "UT MD Anderson Cancer Center", "org_type": "医院", "target": "CCR7", "modality": "antibody", "importance_level": "低", "total_score": 45.5, "institution_score": 30, "track_score": 65, "milestone_score": 45, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "靶点为CCR7，通过阻断抗体抑制肿瘤细胞向淋巴管迁移，在炎性乳腺癌中显示潜在治疗价值，但仅为研究机构preclinical表征和功能验证阶段。机构为医院非商业开发、赛道为抗体阻断但非热门ADC/双抗、开发早期无明确里程碑导致总体评分较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10274", "id": "PJ7ECZ0BZznHJdntvNYd", "source_drug_name": "CCR7-blocking antibody", "title": "CCR7 expression and spatial distribution in inflammatory breast cancer: A baseline characterization for therapeutic targeting", "abstract_text": "Purpose: Inflammatory breast cancer (IBC) is a rare, highly aggressive subtype marked by rapid proliferation, extensive angio-/lymphangiogenesis, and early metastasis. CCR7, a chemokine receptor involved in immune trafficking, promotes tumor migration toward lymphatics via CCL19/CCL21. This study provides an integrated genomic, protein, spatial, and functional evaluation of CCR7 in IBC to assess its therapeutic potential.\nMethods: Clinical analysis used genomic data from HR+ HER2- and TNBC IBC compared with subtype-matched non-IBC. CCR7 expression was assessed in IBC and non-IBC cell lines by immunoblotting; ligand secretion (CCL19/CCL21) in tumor and stromal cells was measured by ELISA. CCR7 localization was evaluated using subcellular fractionation and IF, along with testing of a CCR7-blocking antibody. Multiplex IF was performed on BCM PDX models representing distinct CCR7 genomic and protein states. Functional studies included the CCR7 antagonist Navarixin, CCL19/21-induced migration assays, and generation of CCR7 CRISPR knockout clones.\nResults: CCR7 CNAs occurred in both IBC and non-IBC but did not correlate with mRNA or protein levels. CCR7 protein was broadly expressed, with strongest membranous expression in A3250 and variable levels in IBC-3, SUM-190, and SUM-149. The blocking antibody reduced membranous CCR7 only in A3250, indicating subtype-specific accessibility. IBC cell lines did not secrete CCL19/CCL21, supporting reliance on stromal ligands, which varied by coculture. Across six BCM PDXs, CCR7 was consistently expressed, whereas ligand levels were heterogeneous; MBI-117 showed high CCL19/CCL21. Spatial profiling revealed CCR7⁺ tumor cells aligned along Podoplanin⁺ lymphatics with CCL21⁺ stromal cells and CD163⁺ macrophages enriched around CCR7⁺ emboli. Navarixin reduced proliferation in IBC3 and SUM-190 by 96h, and CCL19/21 enhanced migration in A3250 and SUM-149. CCR7-KO SUM-149 clones were generated, with functional analyses ongoing.\nConclusion: CCR7 expression in IBC is independent of copy number and supported by a ligand-rich microenvironment that positions CCR7⁺ tumor cells along lymphatics. Integrated genomic, spatial, and functional data support CCR7 as a therapeutic target in IBC, with studies ongoing.", "source_company": "UT MD Anderson Cancer Center", "source_org_type": "医院", "row_number": 428, "target_meta": "CCR7", "MOA_meta": "抗体"}, {"drug_name": "anti-GAL1 antibody", "company": "Fundación para la Lucha de las Enfermedades Neurológicas de la Infancia (Fleni)", "org_type": "医院研究机构", "target": "GAL1", "modality": "antibody", "importance_level": "低", "total_score": 45.5, "institution_score": 35, "track_score": 65, "milestone_score": 40, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "药物为靶向Galectin-1（GAL1）的抗体，主要探讨其在胶质母细胞瘤中调控血管生成和代谢重编程的作用，但仅限于体外和患者来源细胞系的preclinical机制研究，未显示药物开发进展。机构为医院/研究机构非药企，赛道虽涉及肿瘤微环境调控但非当前最热门靶点和modality，整体开发阶段早期且无明确里程碑。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1520", "id": "PZ7ECZ0BZznHJdntvNYd", "source_drug_name": "anti-GAL1 antibody", "title": "Galectin-1 as a central regulator of angiogenesis and metabolic reprogramming in glioblastoma", "abstract_text": "Glioblastoma (GB) is the most aggressive tumor of the central nervous system characterized by rapid growth and remarkable resistance to current therapies. Its biology is shaped by profound inter- and intra-tumoral heterogeneity, a highly immunosuppressive microenvironment, and a strong dependence on metabolic and vascular adaptations that allow tumor cells to thrive under hypoxic and nutrient-poor conditions. A subpopulation enriched in glioma stem-like cells (GSCs) plays a central role in these adaptations, sustaining tumor expansion through flexible metabolic and angiogenic programs. Galectin-1 (GAL1), a glycan-binding lectin with multiple roles in the tumor microenvironment, is considerably elevated in gliomas. This led us to investigate whether GAL1 could act as a common regulator of both metabolism and angiogenesis in GB. We established patient-derived GSC lines (G02, G03, G08, G09), a model that preserves the clinical heterogeneity typical of this disease. RNA-seq and functional assays revealed clear differences among cell lines. G02 showed an endothelial-like signature and promoted endothelial cell migration, while G03 was enriched in angiogenesis-related pathways and formed robust tube-like structures in vitro, in line with higher VEGF secretion (p<0.01). Biopsies from the corresponding patients (G02 and G03) recapitulated this biology, displaying broad areas of microvascular proliferation. Inhibition of GAL1 with antibodies or siRNA reduced tube formation mainly in G03, suggesting that not all angiogenic profiles are likely dependent on GAL1. Metabolic analysis further supported this idea. Seahorse analysis showed that G02 and G03 respond to GAL1 depletion by shifting toward opposite metabolic programs, and complementary assays (TMRE, MitoSOX) revealed high mitochondrial activity in G02 (FC=2), while G09 displayed impaired OXPHOS (FC=0.5). Together, our data indicate that both secreted and intracellular GAL1 contribute to the metabolic and angiogenic adaptations that sustain GB growth. These results emphasize that GSCs rely on distinct yet coordinated strategies to obtain resources, and position GAL1 as a central regulator of these processes. Defining the cellular and functional profiles that determine sensitivity to GAL1 inhibition may help guide the development of more precise anti-angiogenic or metabolic therapies for glioblastoma.", "source_company": "Fundación para la Lucha de las Enfermedades Neurológicas de la Infancia (Fleni)", "source_org_type": "医院\n研究机构", "row_number": 433, "target_meta": "not available", "MOA_meta": "抗体"}, {"drug_name": "HSiFox-T7", "company": "Cedars-Sinai Medical Center", "org_type": "医院", "target": "FOXC1", "modality": "other", "importance_level": "低", "total_score": 45.5, "institution_score": 25, "track_score": 75, "milestone_score": 45, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "药物通过HER3靶向纳米颗粒递送5′-三磷酸修饰的FOXC1 siRNA，实现FOXC1沉默并激活肿瘤内源性I型干扰素免疫响应。机构为医院非商业研发、仍处preclinical阶段但显示体内显著抑瘤和免疫激活效果，总分偏低故重要性低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4330", "id": "BVXM_5wBX1NQZOEH-LK6", "source_drug_name": "HSiFox-T7", "title": "HER3-targeted nano-bioparticles deliver 5′-triphosphate-modified FOXC1 siRNA to induce tumor regression and immune activation in HER3⁺ cancers", "abstract_text": "Purpose: HER3 is frequently overexpressed in a range of solid tumors and contributes to resistance against both targeted and chemotherapies. To address this, we developed a triple-function therapeutic approach using HER3-targeted HPK nanocapsid (NC) to deliver FOXC1-specific siRNA, thereby silencing this master transcriptional regulator of tumor aggressiveness and metastasis. The siRNA was synthesized with T7 polymerase to incorporate a 5′-triphosphate (5′-ppp) moiety, which serves as an activator of cellular immune responses. This strategy enables targeted and protected delivery of siRNA cargo, while simultaneously achieving FOXC1 silencing and tumor-intrinsic activation of cellular Interferon response.\nMethods: HPK proteins were engineered to self-assemble into virus-like NCs capable of encapsulating siRNA. We evaluated the properties, stability, and morphology of the nanoparticles. HPK design incorporates the adenovirus penton base protein for membrane penetration and neuregulin for HER3-targeted binding. T7-transcribed FOXC1 siRNAs (HSiFox-T7) were packaged into HPK NCs and evaluated in HER3⁺ tumor cell lines and mouse models. We assessed cytokine production, cell viability, interferon role in cell cytotoxicity, FOXC1 knockdown, migration, immune cell infiltration, and in vivo therapeutic efficacy in both HER3⁺ immunodeficient melanoma and immunocompetent triple-negative breast tumor (TNBC) models.\nResults: The HPK and T7-transcribed siRNA formed stable and smaller nanoparticles compared to synthetic siRNAs. In vitro, T7-derived 5′-ppp siRNAs induced greater cytotoxicity than synthetic controls mainly via activated type I interferon response. HSiFox-T7 achieved robust FOXC1 knockdown, significantly reducing cell migration and viability. In vivo, systemic administration of HSiFox-T7 suppressed tumor growth and increased type I interferon response in immunocompromised HER3+ melanoma models. It also suppressed FOXC1, reduced metastatic lung burden, and increased tumor apoptosis with minimal off-target toxicity while protecting siRNA content in the circulation of immunocompetent TNBC mice model. Treatment enhanced infiltration of NK cells and CD8⁺ T cells into both primary tumors and metastases, indicating strong immunostimulatory effects.\nConclusions: HPK NCs represent a multifunctional platform that combines HER3-targeted delivery, master gene silencing, and immune activation. The HSiFox-T7 system effectively suppressed HER3⁺ tumor growth and metastasis while reprogramming the tumor microenvironment toward immune responsiveness. This triple-action strategy overcomes major barriers in siRNA therapeutics including protecting nucleic acid content in circulation and avoiding off-target effects while offering translational potential for treating aggressive cancers such as TNBC and melanoma.", "source_company": "Cedars-Sinai Medical Center", "source_org_type": "医院", "row_number": 494, "target_meta": "FOXC1", "MOA_meta": "其他"}, {"drug_name": "anti-PD-1", "company": "University of Colorado Anschutz Medical Campus", "org_type": "大学", "target": "PD-1", "modality": "inhibitor", "importance_level": "低", "total_score": 45.5, "institution_score": 35, "track_score": 75, "milestone_score": 30, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "anti-PD-1为经典免疫检查点抑制剂，靶向PD-1，但本摘要仅为大学基础研究，探讨微生物群与抗PD-1疗效的相关性，无新药或具体分子开发信息。机构非药企、未体现药物开发里程碑导致总分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9613", "id": "ClXM_5wBX1NQZOEH-LK6", "source_drug_name": "anti-PD-1", "title": "Distinct microbiota composition in anorectal mucosal melanoma is associated with resistance to immune checkpoint inhibition", "abstract_text": "Anorectal mucosal melanoma (AMM) is a rare and aggressive melanoma subtype characterized by poor responses to immune checkpoint inhibitor (ICI) therapy. While cutaneous melanoma metastases to gastrointestinal (GI) sites often retain strong ICI responses, the mechanisms underlying poor responses in AMM remain unclear. Given that AMM arises in microbial rich mucosal environments, we hypothesized that tumor-associated microbiota may contribute to local immune suppression. To investigate this, we performed 16S rRNA gene sequencing on primary AMM tumors and compared their microbial composition with cutaneous melanoma GI metastases (CM-GI-met) and normal mucosal reference samples, including nasal, rectal, and vaginal swabs. AMM tumors were enriched with Firmicutes Clostridia taxa, including Lactospiraceae and Ruminococcaceae, known butyrate producers associated with immunomodulation. In contrast, CM-GI-met tumors exhibited distinct microbial signatures, with a relatively higher abundance of Fusobacteriaceae and Bacteriodaceae. These patients notably had improved ICI responses compared to AMM primaries. Functional profiling suggested that AMM microbiomes had increased butyrate synthesis, known to create an immunosuppressive tumor microenvironment, which may contribute to poor ICI response. These findings are also seen in our orthotopic rectal mouse melanoma model, which showed reduced tumor growth rates, tumor burden, and overall survival in mice treated with combination vancomycin (Gram-positive selective antibiotic which targets Firmicutes Clostridia) and anti-PD-1 therapy compared to controls and monotherapy. Our findings demonstrate that AMM tumors contain a distinct butyrate-rich microbiome that may contribute to local tumor evasion whereas CM tumors contain a more ICI-permissive microbiome.", "source_company": "University of Colorado Anschutz Medical Campus", "source_org_type": "大学", "row_number": 498, "target_meta": "PD1", "MOA_meta": "抑制剂"}, {"drug_name": "CDK9 inhibitor", "company": "University of Helsinki", "org_type": "大学", "target": "CDK9", "modality": "inhibitor", "importance_level": "低", "total_score": 45.5, "institution_score": 35, "track_score": 65, "milestone_score": 40, "field_heat_score": 55, "bonus_score": 3, "brief_reason": "药物靶向CDK9，通过抑制转录延伸引发病毒模拟和先天免疫激活，具有潜在免疫调节机制；但来自大学机构、仍处于机制研究和动物模型验证阶段，无临床数据，整体开发成熟度较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1493", "id": "EFXM_5wBX1NQZOEH-LK6", "source_drug_name": "CDK9 inhibitor", "title": "‘Translating’ CDK9 inhibitor effects to target prostate cancer", "abstract_text": "Introduction Prostate cancer (PC) is the most common male cancer, and more effective treatments are needed to control the late-stage disease. In the lethal disease, termed castration-resistant PC (CRPC), cancer cells sustain a pro-proliferative gene expression program despite the presence of anti-androgens. This gene expression program is ultimately dependent on CDK9, and compounds targeting it are currently in clinical trials for solid tumors. All cells depend on CDK9 to sustain gene expression, although it is not clear why cancer cells are particularly sensitive to CDK9 targeting drugs.\nExperimental procedures Multi-omics profiling of prostate cancer cell lines was used to understand how cells respond to CDK9 inhibition. Patient samples were used to correlate some of the findings, with data validation ongoing in syngeneic mouse models.\nSummary of the data We show that CDK9 inhibition activates the innate immune response through viral mimicry in PC cells. As expected, targeting CDK9 suppresses overall transcription; however, some genes are expressed in significantly higher levels in this situation. Mechanistically, CDK9 inhibition uncouples the mRNA-processing machinery from RNA polymerase II, and we show that in this situation intron retention is significantly increased. The generated mis-spliced RNAs are prone to form double-stranded RNAs (dsRNA), and full activity of (dsRNA)-activated kinase is required for the CDK9 inhibitor-induced anti-proliferative effects. Accumulation of dsRNAs is known to activate the innate immune response and indeed we show that CDK9 inhibition leads to excessive secretion of immunogenic cytokines.\nConclusions Our data reveal that targeting the transcription elongation kinase CDK9 activates immuno-modulatory signalling in vitro by selectively augmenting translation of certain mRNAs. We are now validating these effects in syngeneic animal models, patient derived organoids, and probing the extent to which the transcriptional and translational programs are rewired. In the long run, our aim is to develop an effective treatment strategy against CRPC.", "source_company": "University of Helsinki", "source_org_type": "大学", "row_number": 502, "target_meta": "CDK9", "MOA_meta": "抑制剂"}, {"drug_name": "P3F1 392-510 peptide mimics", "company": "California Institute of Technology", "org_type": "大学", "target": "PAX3::FOXO1", "modality": "other", "importance_level": "低", "total_score": 45.5, "institution_score": 35, "track_score": 65, "milestone_score": 40, "field_heat_score": 55, "bonus_score": 3, "brief_reason": "P3F1 392-510 peptide mimics针对PAX3::FOXO1融合蛋白的IDR区域，通过干扰其转录hub和活性抑制融合阳性肺泡型横纹肌肉瘤。该项目来自大学机构、处于早期机制研究阶段、pediatric sarcoma未满足需求较高但整体开发成熟度低，故重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5925", "id": "R1XM_5wBX1NQZOEH-LK6", "source_drug_name": "P3F1 392-510 peptide mimics", "title": "Targeting PAX3::FOXO1 condensates in fusion-positive alveolar rhabdomyosarcoma via disordered-region mimetic peptides", "abstract_text": "Background: PAX3::FOXO1 (P3F1) is a fusion oncoprotein that drives fusion-positive alveolar rhabdomyosarcoma (aRMS), a highly lethal pediatric cancer with <30% 5-year survival in high-risk patients. Targeted therapy development has been limited by P3F1’s largely disordered structure and poorly understood interaction mechanisms. Recent work has shown that short peptides targeting intrinsically disordered regions (IDRs) can disrupt transcriptional hubs and impair tumor growth, but this strategy requires identifying key interaction partners that often regulate other signaling pathways. We previously discovered that P3F1 demonstrates a neomorphic hub formation propensity that corresponds with its transcriptional activity, suggesting that disrupting these hubs can hinder said activity.\nPurpose: To design short peptides modelled from the P3F1 IDR itself that disrupt P3F1 hubs and suppress P3F1-mediated transcription and aRMS cell proliferation.\nExperimental Procedures and Results: Using the LacO array assay, an established in-cellulo method that quantifies IDR interaction strength, we discovered that truncating the P3F1 392-510 region significantly decreased IDR interaction strength. Further, the same truncation significantly altered its interaction strength with p300, a key transcriptional coactivator known to promote P3F1’s function. Finally, dual luciferase assay results showed that a 392-510 deletion significantly decreased P3F1’s transactivation ability. Taken together, this suggested that P3F1 392-510 is a key interaction hotspot that influences its transcriptional capability. Sequence analysis revealed that P3F1 392-510 is enriched in cationic and aromatic residues, consistent with cation-π and π-π interactions common in IDRs. FINCHES interaction mapping showed that mutating either all cationic or all aromatic residues in this region reduces P3F1 homotypic interactions, with aromatic-to-alanine mutations producing the stronger effect. Ongoing experiments utilizing the LacO array assay are probing these interaction modes to guide the design of optimized P3F1 392-510 peptide mimics.\nConclusions: P3F1 392-510 is critical for P3F1’s IDR-mediated interactions and transcriptional activity. Its cationic and aromatic composition suggests cation-π and/or π-π interactions as key interaction modes. Future work will experimentally dissect these interaction modes and develop peptide inhibitors informed by this mechanistic insight.", "source_company": "California Institute of Technology", "source_org_type": "大学", "row_number": 532, "target_meta": "PAX3,FOXO1", "MOA_meta": "其他"}, {"drug_name": "EGFR inhibitor", "company": "National Cancer Center Japan", "org_type": "研究机构", "target": "EGFR", "modality": "inhibitor", "importance_level": "低", "total_score": 45.5, "institution_score": 35, "track_score": 75, "milestone_score": 30, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "该记录针对EGFR抑制剂耐药机制的单细胞和空间转录组研究，靶点EGFR在NSCLC中已高度成熟。机构为国家癌症研究中心但非药物开发者，缺乏新药里程碑信息，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/2513", "id": "SJ7ECZ0BZznHJdntvNYd", "source_drug_name": "EGFR inhibitor", "title": "Spatio-temporal analysis of EGFR inhibitor resistant tumor epithelial clusters", "abstract_text": "[Background]Drug-tolerant persister (DTP) cells are a reversible drug-insensitive tumor subpopulation implicated in minimal residual disease (MRD) and recurrence. However, their emergence mechanisms and therapeutic vulnerabilities remain unclear. We previously tracked clonal dynamics in vivo using genetic barcodes and showed that expansion of specific clones contributes to the resistance of EGFR inhibitors. Here, we analyzed non-small cell lung cancer treated with EGFR inhibitors to (1) identify treatment-resistant tumor cell populations and (2) elucidate spatial mechanisms underlying DTP cell emergence.\n[Methods]Tumor samples from the PIT3 trial (UMIN000026197) were analyzed before and after the neoadjuvant EGFR inhibitor therapy. Single-cell (sc) RNA-seq (n = 8) and Visium HD spatial transcriptomics (n = 10) were performed. Spatial datasets were processed using HueTracer (https://github.com/MANO-B/HueTracer), enabling extraction of single-cell-level expression profiles and integration with scRNA-seq.\n[Results]Integrated scRNA-seq analysis (8 specimens, 16,419 cells) identified multiple tumor epithelial clusters, including an EGFR-resistant subcluster enriched in poor responders. This subcluster showed a higher proportion of G1-phase cells, reduced EGFR, and elevated EMT-related genes, suggesting treatment-resistant phenotypes. Rare cells with similar transcriptional features were also detected in responders, indicating the presence of surviving DTP-like cells.\nSpatial transcriptomic analysis (20 specimens, 2,415,876 cells) identified tumor clusters and treatment-responsive regions characterized by island-like residual lesions with necrosis and desmoplasia. Small numbers of surviving cells were designated as DTP candidates and compared with other tumor epithelial cells. Across five cases, meta-analysis of differentially expressed genes revealed consistent upregulation of inflammation- and plasticity-related genes, including ILR-X, TF-X, LAMB3, and TXLNB (FDR < 0.05). GSEA showed enrichment of TNF-α/NFκB signaling, interferon response, EMT, and tissue remodeling pathways, indicating a shared inflammatory and plasticity-enhanced state in DTP candidates.\n[Conclusion]Single-cell and spatial analyses demonstrate that DTP-like cells persisting after EGFR inhibitor therapy exhibit a shared molecular phenotype characterized by heightened inflammation and epithelial plasticity. These features may underlie microscopic residual disease capable of driving post-treatment recurrence, supporting the concept of DTP cells as a potential therapeutic target.", "source_company": "National Cancer Center Japan", "source_org_type": "研究机构", "row_number": 544, "target_meta": "EGFR", "MOA_meta": "抑制剂"}, {"drug_name": "androgen receptor pathway inhibitor", "company": "The Institute of Cancer Research", "org_type": "研究机构", "target": "未披露", "modality": "inhibitor", "importance_level": "低", "total_score": 45.5, "institution_score": 35, "track_score": 65, "milestone_score": 40, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "该项研究聚焦mCRPC中cfDNA核小体足迹分析AR等转录因子活性，未披露具体新AR通路抑制剂药物本身，仅为生物标志物研究。机构为学术研究型、开发阶段为基础研究且无明确药物里程碑导致总体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9902", "id": "MFXM_5wBX1NQZOEH-LO6", "source_drug_name": "androgen receptor pathway inhibitor", "title": "Plasma cell-free DNA nucleosome footprints in metastatic castration-resistant prostate cancer (mCRPC)", "abstract_text": "Background: Transcription factor (TF) activity can be determined by nucleosome footprints in low-pass whole genome sequencing (lpWGS) of plasma cell-free DNA (cfDNA). cfDNA wrapped around nucleosomes is protected from enzymatic digestion, and TFs induce phased nucleosome positioning around their binding sites, which results in oscillatory sequencing coverage and preferential depletion at open chromatin regions. Herein, we quantify nucleosome occupancy at binding sites for hundreds of TFs, evaluating the clinical utility of these functional readouts in plasma taken from subjects treated on the CARD prospective randomized trial of cabazitaxel (CAB) vs second androgen receptor pathway inhibitor (ARPI).\nMethods: Plasma cfDNA lpWGS (median coverage ~1.6x) was used to infer nucleosome footprints at TF binding sites (TFBS) of 682 TFs. Overall, 217 CARD trial subjects comprised a Test cohort and 174 patients receiving a taxane on the FIRSTANA and PROSELICA prospective trials comprised a validation set. cfDNA lpWGS of a cohort of 104 healthy participants was used as a control. Hazard ratios (HR) were computed using Cox proportional hazards models. Odds ratios (OR) were computed using logistic regression. Longitudinal changes between baseline and subsequent timepoints were investigated using linear mixed effect models. All analyses were adjusted for tumor fraction.\nResults: Out of 682 TFs with available binding site annotations, 357 consistently yielded signal-to-noise ratios of at least 2:1 and were further analyzed. Analytical validation utilizing technical replicates (different samples; same time point) and biological replicates (different samples, taken at baseline and screening, weeks apart) was pursued, determining the dynamic range for these TFs at 1000 TFBS each. Assay limits of detection (LOD) and limits of quantification (LOQ) for sequencing coverage and tumor fraction were determined for each TF. Of 357 TFs, 244 were significantly mCRPC associated (Wilcoxon test, adjusted p-value < 0.05) relative to healthy controls, including AR, NKX3-1, E2F1, MYC, MYCN, and MAZ. Predictive analysis in CARD showed accessibility at UBP1 binding sites at baseline was associated with taxane sensitivity over ARSI (OR 1.44, 95% 1.07-1.95, p-value < 0.05). Furthermore, average FOXP1 accessibility scores increased at progression (average increase 1.76, SE 0.49, p-value 0.02), alongside AR (average increase 1.16, SE 0.49, p-value 0.02) and GRHL2 scores (average increase 1.33, SE 0.53, p-value 0.01). These plasma-derived data suggest patients progress with increased AR signaling.\nConclusions: Evaluating nucleosome footprints at TFBS using lpWGS is a robust approach that identifies valuable functional biomarkers of drug sensitivity. Such studies offer the opportunity to interrogate disease progression through serial clinical samples, where phenotype profiling is otherwise unfeasible.", "source_company": "The Institute of Cancer Research", "source_org_type": "研究机构", "row_number": 685, "target_meta": "not available", "MOA_meta": "抑制剂"}, {"drug_name": "anti-CD40", "company": "DKFZ German Cancer Research Center", "org_type": "研究机构", "target": "CD40", "modality": "other", "importance_level": "低", "total_score": 45.5, "institution_score": 35, "track_score": 65, "milestone_score": 40, "field_heat_score": 55, "bonus_score": 0, "brief_reason": "anti-CD40为CD40激动型抗体，通过免疫调节增强抗肿瘤免疫，在乳腺癌小鼠模型中与panobinostat和venetoclax联用显示消除癌干细胞潜力。机构为德国癌症研究中心非商业顶级药企导致机构分较低，整体处于机制研究阶段缺乏明确临床里程碑，总分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/695", "id": "g1XM_5wBX1NQZOEH-LO6", "source_drug_name": "anti-CD40", "title": "Mechanistic basis of panobinostat, venetoclax, and anti-CD40 combination therapy in the immune elimination of cancer stem cells", "abstract_text": "Resistance in breast cancer treatment drives the search for new therapies. Cancer stem cells (CSCs) contribute to metastasis, recurrence, and therapy resistance. Our data suggest that combining panobinostat, venetoclax, and anti-CD40 (aCD40) immunotherapy effectively eliminates CSCs through immune modulation. This triple combination showed superior outcomes in three breast cancer mouse models, though its precise mechanism remains unclear. To dissect these mechansims, we use a multiplex implantable microdevice assay (MIMA) for precise drug delivery, cyclic immunofluorescence for tumor microenvironment characterization, and computational analyses to investigate treatment response and resistance. Single-cell RNA sequencing and multiplex tissue imaging map drug-induced cellular changes. Our results demonstrate that the panobinostat and venetoclax combination (PV) increase intratumoral immune infiltration, recruiting neutrophils, macrophages, and dendritic cells (DCs). Spatial analysis reveals APOE+ myeloid cells accumulating in PV-treated regions. Systemic PVaCD40 treatment enhances tumor killing, reduces CSCs, and improves antigen presentation by activating DCs and macrophages. Mechanistically, macrophages upregulate interferon-induced genes, boosting antigen presentation, while DCs regulate T cell migration and also increase antigen presentation. Interactions between CSCs and DCs/macrophages are elevated, and ligand-receptor analyses indicate that Mif-Cd74 and App-Cd74 signaling mediate CSC-immune cell communication. Collectively, these results provide a mechanistic framework for how Panobinostat-Venetoclax-Anti-CD40 triple combination therapy remodels the tumor microenvironment to eliminate breast CSCs and potentiate antitumor immunity.", "source_company": "DKFZ German Cancer Research Center", "source_org_type": "研究机构", "row_number": 738, "target_meta": "CD40", "MOA_meta": "其他"}, {"drug_name": "anti-OSMR antibody", "company": "Medical College of Wisconsin", "org_type": "大学", "target": "OSMR", "modality": "inhibitor", "importance_level": "低", "total_score": 45.5, "institution_score": 30, "track_score": 60, "milestone_score": 55, "field_heat_score": 50, "bonus_score": 3, "brief_reason": "靶点为OSMR，通过阻断OSMR-OSM信号抑制STAT3激活，抗体阻断配体结合、诱导内化和降解，针对卵巢癌等实体瘤显示体内抗肿瘤和增敏顺铂作用。机构为大学非商业研发，处于preclinical向ADC/BiTE衍生阶段，靶点新兴但非主流热门，整体热度和里程碑有限。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1858", "id": "jVXM_5wBX1NQZOEH-LO6", "source_drug_name": "anti-OSMR antibody", "title": "Targeting OSMR signaling networks for precision oncology", "abstract_text": "Oncostatin M (OSM) is a member of the IL-6 cytokine subfamily that binds to the Oncostatin M receptor (OSMR) and activates JAK/STAT-mediated oncogenic signaling. Our single-cell RNA sequencing (scRNA-seq) revealed that OSMR is highly expressed in tumor epithelial cells, whereas its ligand, OSM, is predominantly produced by tumor-associated macrophages. Our data established that OSM-induced STAT3 activation was markedly more robust than that induced by other IL-6 family ligands, leading to enhanced OSMR-driven cellular invasion, migration, and tumor growth. Overall, our findings highlight OSMR signaling as a promising therapeutic vulnerability in ovarian cancer. To address the lack of OSMR-targeted treatments, this study aims to develop a monoclonal antibody that blocks OSMR signaling in cancer cells without harming normal epithelial, stromal, or immune cells. We employed sc-RNA seq, clinical samples and signaling pathway analysis to characterize how OSMR serves as a signaling addiction mechanism in cancer cells. To elucidate the mechanism of actions, we performed live-cell image analysis, receptor dimerization assays, in-cell Western analyses and in vivo tumor growth assays.Our data shows that anti-OSMR antibody effectively blocked the binding of the ligand OSM to OSMR and subsequently inhibited OSMR dimerization with IL6ST. We also observed that OSMR antibody induced internalization and cytoplasmic degradation of OSMR, resulting in a marked reduction in STAT3 activation, tumor cell invasion, tumor growth, and metastasis. Transcriptome-based analyses, along with in vitro and functional assays, further revealed that cisplatin-resistant ovarian cancer cells express significantly higher levels of OSMR compared to cisplatin-sensitive cells, and that these resistant cells depend on OSMR signaling for aggressive tumor growth. Consistently, the treatment of anti-OSMR antibodies sensitized cancer cells to cisplatin therapy both in vitro and in vivo.In sum, our studies demonstrate that OSMR represents a therapeutically targetable driver of highly aggressive and chemo-resistant ovarian cancers. We also observed an elevated expression of OSMR in pancreatic cancer, glioblastoma, and stomach adenocarcinoma, suggesting a broader clinical applicability of OSMR therapy. Based on the promise of our anti-OSMR therapy in vivo, we are actively developing antibody-drug conjugates (ADCs) and bispecific T-cell engagers (BiTEs) of OSMR antibody to further enhance its antitumor efficacy.", "source_company": "Medical College of Wisconsin", "source_org_type": "大学", "row_number": 744, "target_meta": "OSMR", "MOA_meta": "抑制剂"}, {"drug_name": "Ad.sTGFβR", "company": "University of Illinois at Chicago", "org_type": "大学", "target": "未披露", "modality": "oncolytic adenovirus", "importance_level": "低", "total_score": 45.5, "institution_score": 25, "track_score": 75, "milestone_score": 40, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "Ad.sTGFβR为hTERT驱动的溶瘤腺病毒，携带可溶性TGF-β受体Fc融合蛋白作为转基因，主要用于工具性研究卵巢癌TGF-β和GM-CSF信号机制，而非明确药物开发靶点。大学机构+工具模型阶段导致总体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1422", "id": "lFXM_5wBX1NQZOEH-LO6", "source_drug_name": "Ad.sTGFβR", "title": "Modeling late-stage ovarian cancer and validating oncolytic adenoviral tools for transgene expression and tumor monitoring", "abstract_text": "Purpose: High-grade serous ovarian cancer (HGSOC) is characterized by profound immune exclusion and peritoneal spread, hypothesized to be orchestrated by the TGF-β and GM-CSF cytokines. We established an immunocompetent murine model of advanced HGSOC and evaluated the tumor selectivity and transgene delivery efficiency of hTERT-driven oncolytic adenoviruses encoding GM-CSF and/or a soluble TGF-β receptor Fc fusion (sTGFβR-Fc).\nExperimental Procedures: A syngeneic orthotopic model of advanced HGSOC was established by intraperitoneally injecting luciferase-labeled MOE-KRAS/PTEN (MKP) cells into immunocompetent FVB/N mice. Tumor burden was monitored longitudinally by bioluminescence imaging (BLI). Four hTERT-driven oncolytic adenoviruses (Ad.Null, Ad.GM-CSF [Ad.GM], Ad.sTGFβR [Ad.sT], Ad.sTGFβR.GM-CSF [Ad.sT.GM]) were evaluated in vitro for infectivity, cytolytic activity (Incucyte/caspase 3/7), and transgene expression (flow cytometry) in MKP tumor cells, NIH 3T3 fibroblasts, and 3T3-derived cancer-associated fibroblasts (CAFs).\nResults: Serial BLI showed consistent peritoneal tumor engraftment and progression by day 26 (n = 14) confirming model fidelity for late-stage disease. In vitro, IncuCyte live-cell imaging revealed strong, selective apoptosis in MKP cells following oncolytic infection, while NIH 3T3 fibroblasts and CAFs (non-tumor controls) showed minimal response. Apoptotic activity in MKP cells rose sharply at 30-35 hours and peaked at 45 hours post-infection (>60-80% fold increase in caspase3/7+ area over untreated but minimal apoptotic activity in 3T3 and CAFs (<8-fold over untreated). Notably, among virus constructs, Ad.GM and Ad. Null induced the most rapid and robust apoptosis, whereas Ad. sT and Ad.sT.GM showed significantly delayed and reduced effects (Ad.GM vs Ad. Null: p = 0.0042; Ad. sT vs Ad.GM or Ad. Null: p < 0.0001; 2-way ANOVA with Sidak’s test). Transgene expression was quantified by flow cytometry following 48-hour infection. Ad.GM and Ad.sT.GM treatments produced GM-CSF positive cells (2.25% and 1.04% gated, mean fluorescence intensity 6217.54 and 5508.2 respectively) while Ad.sT and Ad.sT.GM treatments produced sTGFβR-Fc positive cells (8.04% and 9.75% gated, mean fluorescence intensity 85092.63 and 84097.65 respectively); live cell frequencies decreased in treated groups (61.45-67.83%) compared to untreated (96.32%) controls. These results demonstrate selective transgene expression and cytotoxicity in tumor cells achieved by the engineered oncolytic constructs.\nConclusions: These data confirm the fidelity for advanced-stage HGSOC model and establish oncolytic adenoviral platforms as effective mechanistic tools—functioning both as cytolytic agents and as delivery vehicles for functional transgenes—to mechanistically dissect TGF-β and GM-CSF signaling in ovarian cancer.", "source_company": "University of Illinois at Chicago", "source_org_type": "大学", "row_number": 748, "target_meta": "not available", "MOA_meta": "溶瘤病毒"}, {"drug_name": "TNF-neutralizing antibody", "company": "Stanford University", "org_type": "大学", "target": "TNF", "modality": "inhibitor", "importance_level": "低", "total_score": 45.5, "institution_score": 35, "track_score": 60, "milestone_score": 45, "field_heat_score": 55, "bonus_score": 0, "brief_reason": "药物为TNF中和抗体，主要针对TNF靶点，通过阻断TNF-LRG1轴缓解癌症诱导的血管重塑和动脉粥样硬化；Stanford大学学术研究，仅动物模型初步扰动实验，缺乏药物开发推进和临床转化迹象，故整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1526", "id": "m1XM_5wBX1NQZOEH-LO6", "source_drug_name": "TNF-neutralizing antibody", "title": "Cancer reprograms the remote vascular microenvironment to promote atherosclerosis", "abstract_text": "Cancer releases a broad repertoire of circulating cytokines and angiogenic factors that remodel distant tissues. However, the remote vascular consequences of tumor-derived inflammatory signaling remain incompletely understood. Our preliminary data suggest that cancer activates a TNF-driven, LRG1-dependent endothelial pro-angiogenic pathway implicated in remote vascular remodeling. We profiled vascular responses to colorectal tumors using bulk and single-cell RNA sequencing of aortic tissues from tumor-bearing versus control mice across diverse backgrounds, endothelial assays stimulated with tumor-conditioned media, O-link proteomics to define tumor-induced circulating mediators, and in vivo perturbation of the TNF-LRG1 axis using a TNF-neutralizing antibody or endothelial-targeted AAV-LRG1 knockdown. Across independent human datasets, we further observed that large cohort studies from both Europe and the United States demonstrate an increased risk of atherosclerotic CVD in cancer survivors, tumor resection is associated with a reduced risk of atherosclerotic events, and biobank tissues from cancer patients display elevated vascular TNF-LRG1 signaling, supporting clinical relevance. In conclusion, cancer upregulates TNF to activate an LRG1-dependent endothelial pathway, driving angiogenesis and vascular remodeling. These findings uncover a previously unrecognized tumor-CVD interaction and identify the TNF-LRG1 axis as a potential therapeutic target to mitigate cancer-induced vascular dysfunction.", "source_company": "Stanford University", "source_org_type": "大学", "row_number": 752, "target_meta": "TNF-α", "MOA_meta": "抑制剂"}, {"drug_name": "selective RET inhibitor", "company": "Gustave Roussy", "org_type": "医院", "target": "RET", "modality": "inhibitor", "importance_level": "低", "total_score": 45.5, "institution_score": 25, "track_score": 75, "milestone_score": 40, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "药品为selective RET inhibitor，靶点明确为RET融合阳性NSCLC中的RET激酶。机构为医院而非药企导致institution_score较低，摘要为回顾性临床分析而非药物开发新数据导致milestone_score不高，总分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9771", "id": "rFXM_5wBX1NQZOEH-LO6", "source_drug_name": "selective RET inhibitor", "title": "Prognostic and predictive effects of TP53 co-mutations and RET fusion partners in RET-rearranged advanced NSCLC", "abstract_text": "Background: RET fusions occur in ~1-2% of advanced NSCLC (aNSCLC). Selective RET inhibitors (SRIs) significantly improve outcomes, yet ~10% of patients progress by 6 months and ~30% by 12 months. Predictors of response or early progression remain poorly defined.\nMethods: A multicenter retrospective analysis (RET-MAP) of RET+ aNSCLC from 47 international centers evaluated clinical/genomic correlates of SRI outcomes. Multivariable Cox models estimated progression-free (PFS) and overall survival (OS) and tested interactions with first-line (1L) SRI versus chemotherapy ± immune checkpoint inhibitor (CH±ICI). In parallel, genomic/transcriptomic features were characterized in an external Caris Life Sciences (CLS) RET+ aNSCLC cohort.\nResults: Among 510 RET-MAP patients (median age 63; 59% female; 36% ever-smokers; 92% adenocarcinoma), 401 received an SRI (1L n=151; later lines n=250). Median PFS on SRI (any line) was 17.1 months (95% CI, 14.5-21.1), median OS 30.4 months (95% CI, 27.0-41.1). TP53 co-mutation was present in 27% (78/292 tested) and was associated with shorter PFS (8.9 vs 19.2 months; p<0.001) and OS (22.7 vs 30.9 months; p=0.002), without a significant treatment-by-TP53 interaction for 1L SRI versus CH±ICI (p=0.22). Fusion partner contributed with additional signal: KIF5B (73%, 274/373) had inferior PFS (13.4 vs 60.2 months; p<0.001) and OS (26.6 vs 73.0 months; p=0.002) compared with CCDC6 (17%, 65/373), and a significant treatment-by-fusion interaction favored SRI over CH±ICI in CCDC6 versus KIF5B (p=0.007). On multivariate analysis, shorter PFS and OS were independently associated with TP53 mutation (HR 1.74, p<0.001; HR 1.77, p=0.001), KIF5B fusion (HR 1.98, p=0.002; HR 1.64, p=0.040), ECOG ≥2 (HR 2.20, p<0.001; HR 3.06, p<0.001), and brain metastases (HR 1.59, p=0.003; HR 1.88, p<0.001); worse OS was associated with non-adenocarcinoma histology (HR 1.74, p=0.049) and smoking (HR 1.42, p=0.034). Notably, KIF5B fusions were enriched for TP53 mutations versus CCDC6 (40% vs 19.6%, p=0.011), suggesting partially overlapping biology. In the CLS cohort (N=211), TP53-mutant tumors (74/211) were enriched for RB1 mutations, had higher PD-L1 expression and tumor mutational burden, and demonstrated increased M1 macrophage/B-cell infiltration with reduced neutrophils; by fusion partner, CCDC6 showed higher PD-L1, while global transcriptomes were otherwise similar to KIF5B.\nConclusions: In RET+ aNSCLC, TP53 mutation is prognostic for inferior outcomes on SRIs but not predictive of differential benefit versus CH±ICI. Fusion partner carries both prognostic and predictive relevance; CCDC6 is associated with a more indolent course and greater relative benefit from SRI. External profiling supports an inflammatory microenvironment in TP53-mutant disease, reinforcing biologically distinct—and clinically meaningful—subsets within RET-driven lung cancer.", "source_company": "Gustave Roussy", "source_org_type": "医院", "row_number": 767, "target_meta": "RET", "MOA_meta": "抑制剂"}, {"drug_name": "anti-GAL1 neutralizing monoclonal antibody (clone 3)", "company": "Instituto de Biología y Medicina Experimental (IBYME, CONICET)", "org_type": "研究机构", "target": "Galectin-1 (GAL1)", "modality": "monoclonal antibody", "importance_level": "低", "total_score": 45.5, "institution_score": 25, "track_score": 65, "milestone_score": 55, "field_heat_score": 60, "bonus_score": 2, "brief_reason": "药物为针对Galectin-1的中和单抗，机制涉及调控激素驱动的乳腺重塑和早期转移播散，在乳腺癌模型中显示阻断可减少分支形态发生、CTC释放和肺转移。公司为阿根廷学术研究机构而非商业药企，得分较低；赛道为新型免疫靶点但非热门ADC/双抗，处于早期动物治疗实验阶段，整体热度和里程碑有限。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6014", "id": "zFXM_5wBX1NQZOEH-LO6", "source_drug_name": "anti-GAL1 neutralizing monoclonal antibody (clone 3)", "title": "Galectin 1 as a regulator of hormone driven mammary remodeling and early dissemination with therapeutic potential in breast cancer", "abstract_text": "Galectin-1 (GAL1) is a glycan-binding protein broadly known to shape tumor progression by promoting immune evasion and metastatic dissemination. While GAL1 is well recognized as an immunomodulator in multiple cancer types, its role in hormone-driven mammary gland biology and early tumor evolution remains poorly defined. Using our established MMTV-PyMT model WT or KO for GAL1 (Lgals1-/-), we previously demonstrated that GAL1 deficiency delays tumor onset, reduces metastatic burden, and diminishes mammary branching morphogenesis. Unexpectedly, we also observed a decreased Progesterone Receptor (PR) expression in luminal cells from Lgals1-/- mice in both normal and transformed mammary glands. These findings suggested that GAL1 may act as a critical regulator of hormone-driven mammary gland development. To test this hypothesis, we stimulated C57BL/6 Lgals1+/+ and Lgals1-/- mice with a pellet containing Medroxyprogesterone acetate (MPA), a synthetic progestin, and observed that GAL1-deficient mice exhibited a significantly reduced branching index in response to MPA stimuli. RNA-seq analysis of MPA-treated or control mammary glands further revealed that canonical progesterone-responsive genes such as Tnfsf11 (Rankl) and Wnt4 were attenuated in Lgals1-/- glands. To determine if GAL1 absence perturbs epithelial cell hierarchies, we profiled mammary epithelial cell populations by spectral flow cytometry using EpCAM, CD49f, CD49b and Sca1 markers among CD45neg cells. GAL1-deficient glands exhibited reduced MaSC and ER+ luminal progenitor cell compartments, suggesting that GAL1 helps maintain lineage balance during the development of the mammary gland. This finding is particularly relevant given that this population has been recognized as an early cell of origin in neoplastic transformation. To further interrogate the therapeutic relevance of GAL1 blockade, we used an MMTV-HER2+ model of breast cancer. We developed a GAL1 (clone 3) neutralizing monoclonal antibody and treated MMTV-HER2+ mice (15mg/kg, twice a week) from week 14 of age (preneoplastic stage), through week 19. Therapeutic blockade of GAL1 reduced branching morphogenesis, curtailed the release of early circulating tumor cells (CTCs), decreased the number of transformed ducts, and reduced lung metastasis. Importantly, anti-GAL1 treatment led to reduced PR expression in mammary luminal cells and depleted GAL1 in serum, further confirming the blockade's effectiveness. Together, these findings introduce Galectin-1 as a regulator of progesterone-driven epithelial remodeling and early metastatic spreading. By linking GAL1 to hormone signaling, epithelial hierarchy, and early dissemination, our study positions GAL1 as a promising therapeutic target for treating metastatic breast cancer progression.", "source_company": "Instituto de Biología y Medicina Experimental\nIBYME, CONICET\nInstitute de Biología y Medicina Experimental", "source_org_type": "研究机构", "row_number": 795, "target_meta": "LGALS1", "MOA_meta": "单抗"}, {"drug_name": "CAR T cell therapy", "company": "Stanford University", "org_type": "大学", "target": "未披露", "modality": "CAR", "importance_level": "低", "total_score": 45.5, "institution_score": 35, "track_score": 85, "milestone_score": 20, "field_heat_score": 75, "bonus_score": 0, "brief_reason": "CAR-T属于细胞治疗热门赛道且领域热度高，但斯坦福大学作为学术机构非产业化主体，且无摘要导致靶点和具体开发进展完全未披露，里程碑价值无法评估。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/656", "id": "bJ7ECZ0BZznHJdntvNYd", "source_drug_name": "CAR T cell therapy", "title": "Emerging approaches in CAR T cell therapy for B-cell leukemia and lymphoma", "abstract_text": "There is no abstract associated with this presentation.", "source_company": "Stanford University", "source_org_type": "大学", "row_number": 855, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "CAR T cells", "company": "Houston Methodist Research Institute", "org_type": "研究机构", "target": "未披露", "modality": "CAR", "importance_level": "低", "total_score": 45.5, "institution_score": 35, "track_score": 85, "milestone_score": 20, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "该CAR T细胞针对胶质母细胞瘤，通过调控G3BP1影响功能效能，但摘要被禁未披露具体靶点和机制细节。机构为研究机构非头部药企，得分较低；虽CAR-T赛道热门且GBM领域有未满足需求，但仅preclinical初步研究且信息极少，整体重要性有限。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11522", "id": "Q1XM_5wBX1NQZOEH-LS6", "source_drug_name": "CAR T cells", "title": "Modulation of G3BP1 influences the functional efficacy of CAR T cells against glioblastoma", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Houston Methodist Research Institute", "source_org_type": "研究机构", "row_number": 878, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "folate-conjugated copolymer", "company": "Association of Clinical Immunology and Cancer Research", "org_type": "研究机构", "target": "YAP/TAZ-HIPPO oncoproteins", "modality": "other", "importance_level": "低", "total_score": 45.5, "institution_score": 25, "track_score": 85, "milestone_score": 30, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "药物通过叶酸偶联共聚物靶向抑制YAP/TAZ-HIPPO癌蛋白，针对胰腺癌进展和转移，具有新颖无药物机制。机构为普通研究机构、开发阶段不明且摘要禁运导致信息有限、preclinical强度未知，总分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11296", "id": "ilXM_5wBX1NQZOEH-LS6", "source_drug_name": "folate-conjugated copolymer", "title": "Cutting-edge, drug-free targeted cancer therapeutic: Smart folate-conjugated copolymer intrinsically disables the YAP/TAZ-HIPPO oncoproteins and abrogates pancreatic cancer progression and metastasis", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Association of Clinical Immunology and Cancer Research", "source_org_type": "研究机构", "row_number": 930, "target_meta": "YAP/TAZ", "MOA_meta": "其他"}, {"drug_name": "DMB", "company": "Baylor College of Medicine", "org_type": "大学", "target": "GSDMD", "modality": "other", "importance_level": "低", "total_score": 45.5, "institution_score": 30, "track_score": 75, "milestone_score": 40, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "DMB为GSDMD激动剂，通过诱导pyroptosis靶向非凋亡适应性机制克服食管腺癌化疗耐药。机构为大学非商业研发、仅体外工具化合物筛选阶段无明确临床推进，赛道为新兴pyroptosis调控但整体开发早期导致总分较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/12282", "id": "wVXM_5wBX1NQZOEH-LS6", "source_drug_name": "DMB", "title": "Elucidating and overcoming therapeutic resistance in esophageal adenocarcinoma", "abstract_text": "Background: Esophageal adenocarcinoma (EAC) accounts for over 80% of esophageal cancers in the United States and remains a highly lethal malignancy with poor prognosis and rising incidence. Despite advances in therapy, recurrence occurs in most EAC patients, largely due to the emergence of therapeutic resistance. Resistance can be intrinsic or acquired from a rare subpopulation known as Drug Tolerant Persister (DTP) cells, which survive cytotoxic therapy through non-genetic adaptive mechanisms. Unlike genetic resistance, the drug-tolerant state is reversible upon drug withdrawal. This study aims to establish cisplatin-derived DTP(CDDP-DTP) and drug-resistant (CDDP-DR) EAC cell models to elucidate resistance mechanisms, identify therapeutic vulnerabilities, and develop strategies to overcome resistance and prevent recurrence in EAC.\nMethods: CDDP-DTP cells were generated by exposing EAC cells to the IC₈₀ of CDDP for four days, while CDDP-DR cells were developed via stepwise dose escalation based on the IC₅₀. Cytotoxic effects of compounds targeting ferroptosis, pyroptosis, and epigenetic regulation (RSL3, DMB, BIX-01294, and GSK3326595) were evaluated by MTS assays in four EAC cells (FLO-1, OE19, OE33, SK-GT-4). Drug synergy was analyzed using the Combenefit tool. BH3 profiling was performed to assess mitochondrial apoptotic priming and anti-apoptotic dependency. Seahorse assay was used to evaluate cellular metabolism. Cell cycle distribution and cell death were analyzed by propidium iodide (PI) and annexin V/PI staining. Gene and protein expression were measured by quantitative real-time polymerase chain reaction (RT-qPCR) and western blot.\nResults: CDDP-DTP EAC cells exhibited reduced proliferation and upregulation of canonical DTP markers, while CDDP-DR cells displayed >2-fold increased resistance to CDDP, elevated ATF4 expression, an epithelial-to-mesenchymal transition (EMT) phenotype, and resistance to apoptosis accompanied by metabolic reprogramming. Among compounds targeting non-apoptotic, non-genetic adaptive mechanisms, RSL3, DMB and BIX-01294 effectively suppressed EAC cell growth compared with GSK3326595. Notably, BIX-01294 combined with CDDP and DMB combined with a Bcl-xL inhibitor exhibited synergistic cytotoxicity in EAC cells. The target proteins of these compounds—GPX4, GSDMD, and G9A—were upregulated in both TCGA datasets and EAC cells, further highlighting their potential roles as mediators of therapeutic resistance and as promising therapeutic targets.\nConclusions: This study successfully established CDDP-DTP and CDDP-DR models of EAC and revealed that targeting non-apoptotic, adaptive mechanisms can enhance therapeutic response. These findings lay the foundation for multi-omic characterization of resistant EAC populations and support exploration of non-apoptotic vulnerabilities to undermine recurrence and improve long-term outcomes in EAC.", "source_company": "Baylor College of Medicine", "source_org_type": "大学", "row_number": 975, "target_meta": "GSDMD", "MOA_meta": "其他"}, {"drug_name": "anti-PD-L1 antibody", "company": "Seoul National University", "org_type": "大学", "target": "PD-L1", "modality": "inhibitor", "importance_level": "低", "total_score": 45.5, "institution_score": 30, "track_score": 75, "milestone_score": 35, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "药品为anti-PD-L1抗体，靶点PD-L1；研究机构为大学，AHR阻断联合anti-PD-L1在TNBC模型中显示克服耐药的初步体内证据，但仍处于preclinical阶段且非新药开发主体，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5264", "id": "Mp7M_5wBZznHJdnt_W3O", "source_drug_name": "anti-PD-L1 antibody", "title": "Targeting AHR overcomes PD-L1-driven resistance to immune checkpoint blockade in triple-negative breast cancer", "abstract_text": "Introduction: Triple-negative breast cancer (TNBC) has higher tumor immunogenicity than other subtypes, and immune checkpoint inhibitors (ICIs) targeting the PD-1/PD-L1 axis have been applied in its treatment. However, responses to immune checkpoint blockade (ICB) remain limited by intrinsic and acquired resistance, highlighting the need for predictive biomarkers and new combination strategies to improve anti-PD-L1 efficacy.The aryl hydrocarbon receptor (AHR) regulates immune responses and PD-L1 expression, promoting an immunosuppressive tumor microenvironment (TME). AHR signaling may also interfere with interferon-mediated immune activation and affect ICB response. This study aimed to examine how AHR activation contributes to anti-PD-L1 resistance in PD-L1 overexpressing TNBC and whether AHR blockade enhances therapeutic efficacy.\nMethods: PD-L1-overexpressing (PD-L1 OE) and control (Ctl) 4T1 cells were generated. The AHR antagonist (CH-223191) and anti-PD-L1 antibody were applied in vitro and in vivo. Flow cytometry, western blotting, cell proliferation assay, quantitative RT-PCR, immunohistochemistry (IHC), and co-culture of macrophages and cancer cells were performed. An orthotopic syngeneic mouse model was established by injecting 4T1 Ctl or PD-L1 OE cells into the mammary fat pad. Mice were treated with CH-223191 (5 mg/kg, i.p., four times weekly) and anti-PD-L1 antibody (150 µg, i.p., twice weekly), alone or in combination.\nResults: PD-L1 OE tumors showed reduced responsiveness to anti-PD-L1 therapy compared with control in vivo, confirming intrinsic resistance to ICB. AHR expression was elevated at both RNA and protein levels in PD-L1 OE tumors after anti-PD-L1 treatment. Combination therapy with CH-223191 and anti-PD-L1 antibody tended to suppress tumor growth compared with monotherapy, suggesting an ability to overcome PD-L1-driven resistance in vivo. In vitro, CH-223191 reduced 4T1 viability in a dose-dependent manner, suggesting a potential tumor-intrinsic role of AHR signaling. Co-culture of PD-L1 OE 4T1 cells with macrophages promoted M2-like polarization, supporting an immunosuppressive microenvironment. Collectively these findings suggest that AHR activation contributes to anti-PD-L1 resistance by promoting an immunosuppressive TME, and that AHR blockade could enhance anti-PD-L1 efficacy in TNBC.\nConclusions: AHR activation was linked to PD-L1-driven anti-PD-L1 resistance, and AHR inhibition enhanced responsiveness in vivo. These findings suggest that AHR mediates PD-L1 axis-driven resistance and that its inhibition may serve as a promising combination strategy in TNBC. Further studies should elucidate the mechanistic link between AHR signaling and PD-L1-mediated immune regulation and validate its therapeutic potential.", "source_company": "Seoul National University", "source_org_type": "大学", "row_number": 982, "target_meta": "PDL1", "MOA_meta": "抑制剂"}, {"drug_name": "GRN blockade", "company": "Indiana University School of Medicine", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 45.5, "institution_score": 30, "track_score": 75, "milestone_score": 40, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "GRN blockade指宿主progranulin抑制，机制为重编程TME、松弛基质并增强MHC-II而减弱MHC-I驱动的细胞毒免疫，主要基于Grn-/-小鼠模型的preclinical研究，未披露具体药物靶点或modality。机构为大学非商业研发，得分较低；赛道为肿瘤免疫TME重编程有一定热度，但仅动物KO数据无明确药物开发里程碑，总分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5153", "id": "f57ECZ0BZznHJdntvNYd", "source_drug_name": "GRN blockade", "title": "GRN deficiency loosens stromal barriers and enhances MHC-II signaling yet reduces MHC-I driven cytotoxic immunity", "abstract_text": "Progranulin (GRN) is a multifunctional regulator of tissue remodeling and myeloid biology. Although neuroprotective in the CNS, increasing evidence indicates that GRN supports a fibrotic and immune suppressive tumor microenvironment.We investigated whether host GRN restrains anti-tumor immunity and whether its inhibition could be therapeutically leveraged. Using C57BL/6J Grn-/- mice across three syngeneic models (KPC pancreatic ductal adenocarcinoma, B16-F10 melanoma, MC38 colorectal carcinoma), GRN loss consistently delayed tumor growth, with the most pronounced effect in KPC subcutaneous tumors, indicating a substantive but incomplete contribution of host GRN to tumor control.Single-cell RNA-seq and cell-cell interaction analyses of KPC tumors revealed coordinated rewiring of antigen presentation and stromal programs in Grn-/- hosts: MHC-II signaling predominantly B to T was increased, whereas MHC-I inputs decreased. Cancer-associated fibroblasts exhibited downregulation of chemokine/GPCR sensing, ER-phagosome and complement pathways. CAF composition shifted toward iCAF expansion with mCAF/vCAF reduction, and fibroblast→tumor ECM adhesion pairs (COL/FN1/LAM→CD44/SDC) were diminished, consistent with a loosened stromal matrix.In T cells, CD4⁺/CD8⁺ central or resident memory compartments expanded, while cytotoxic and exhausted CD8⁺ populations declined; pseudotime analyses demonstrated attenuated progression from memory toward cytotoxic or exhausted endpoints.Collectively, these data indicate that host GRN sustains a myeloid-CAF program that strengthens stromal tension and supports MHC-I driven T-cell terminal differentiation. GRN loss relaxes this circuit, reducing MHC-I availability while enhancing B-T MHC-II engagement, which shifts T cells toward memory states and limits cytotoxic output. These findings identify GRN blockade as a TME reprogramming strategy that should be paired with agents restoring CD8⁺ signal-1 (MHC-I) to convert enlarged memory pools into durable cytotoxic control in PDAC.", "source_company": "Indiana University School of Medicine", "source_org_type": "大学", "row_number": 994, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "liposome-encapsulated SPARC peptide", "company": "Wake Forest University School of Medicine", "org_type": "大学", "target": "ITGB1", "modality": "other", "importance_level": "低", "total_score": 45.5, "institution_score": 35, "track_score": 45, "milestone_score": 55, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "药物通过脂质体包裹的SPARC肽靶向抑制肿瘤细胞ITGB1信号，阻断脑转移定植；大学机构非商业化开发、modality非热门赛道、仅preclinical概念验证，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10663", "id": "5J7M_5wBZznHJdnt_W3O", "source_drug_name": "liposome-encapsulated SPARC peptide", "title": "Aging attenuates brain metastasis in lung cancer through the MT1G/NF-κB/SPARC signaling", "abstract_text": "Aging is a major risk factor for cancer, with incidence and mortality increasing significantly with age across most cancer types. With the global population aged over 60 projected to rise from 12-22 percent by 2050, understanding the relationship between aging and cancer is critically important. Aging and cancer share several hallmarks—including cumulative genetic damage, immune senescence, altered nutrient sensing, and chronic low-grade inflammation. This overlap implies that age-related biological changes may not only correlate with increased cancer incidence but also influence tumor progression and metastasis. Despite this preconceived notion, population-based epidemiological studies have revealed an inverse association between aging and brain metastasis incidence in lung cancer, with unclear molecular mechanism(s). Here, we show a significantly lower incidence of brain metastasis in aged lung cancer patients compared to younger patients or those with brain metastasis from other cancers, based on analysis of the SEER population-based cancer registry. Mechanistically, aging activates MT1G/NFκB signaling in reactive astrocytes within the brain, leading to increased secretion of SPARC from A1 type reactive astrocytes, which suppresses tumor growth by inhibiting ITGB1 signaling in tumor cells, thereby limiting brain colonization. Notably, therapeutic targeting of ITGB1 using liposome-encapsulated SPARC peptide effectively suppresses brain tumor growth and metastasis, supporting its tumor-suppressive role. These findings uncover an age-associated protective mechanism and provide a compelling rationale for developing targeted therapies to prevent or treat brain metastasis in younger lung cancer patients.", "source_company": "Wake Forest University School of Medicine", "source_org_type": "大学", "row_number": 1112, "target_meta": "ITGB1", "MOA_meta": "其他"}, {"drug_name": "PLD1-selective inhibitor", "company": "Asan Medical Center, University of Ulsan College of Medicine", "org_type": "医院", "target": "PLD1", "modality": "inhibitor", "importance_level": "低", "total_score": 45.5, "institution_score": 35, "track_score": 65, "milestone_score": 40, "field_heat_score": 50, "bonus_score": 0, "brief_reason": "靶点为PLD1（磷脂酶D1），通过抑制糖酵解和代谢应激促进宫颈鳞癌细胞凋亡，具有亚型特异性代谢脆弱性。机构为医院/大学类型非商业化药企，处于工具化合物或前临床研究阶段，无明确药物开发里程碑，赛道热度中等偏上但整体开发成熟度低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4001", "id": "tZ3ECZ0B4z9FlvORyiZD", "source_drug_name": "PLD1-selective inhibitor", "title": "Phospholipase D1 overexpression drives metabolic survival and stress resistance in cervical cancer", "abstract_text": "Background: Cervical squamous cell carcinoma (SCC) and adenocarcinoma (ADC) are clinically and biologically distinct subtypes, yet the metabolic drivers of SCC aggressiveness remain poorly understood. Phospholipase D1 (PLD1), a lipid-modifying enzyme involved in oncogenic signaling and cancer metabolism, has been reported to be elevated in various malignancies. However, its subtype-specific expression pattern and functional relevance in cervical cancer have not been clearly delineated.\nMethods: PLD1 expression was evaluated using TCGA datasets and validated in primary cervical tumors by qRT-PCR, PLD activity assays, and immunohistochemistry. Functional studies were performed in primary SCC and ADC cells using shRNA-mediated PLD1 knockdown or a PLD1-selective inhibitor. Apoptosis, ATP levels, glycolytic activity, clonogenic survival, and invasion were measured under basal and metabolic stress conditions.\nResults: PLD1 was significantly overexpressed in SCC compared with ADC at the mRNA, protein, and enzymatic activity levels. PLD1 inhibition markedly decreased SCC cell survival, whereas ADC cells exhibited minimal sensitivity. PLD1 blockade reduced glycolytic flux and ATP production and increased apoptosis under serum starvation, glucose restriction, and hypoxia. PLD1 knockdown also impaired clonogenic survival and suppressed invasion. These effects were further enhanced by co-treatment with the glycolysis inhibitor 2-deoxy-D-glucose, highlighting a strong dependency of SCC cells on PLD1-mediated metabolic regulation.\nConclusions: PLD1 is selectively upregulated in cervical SCC and serves as a key regulator of glycolysis, energy homeostasis, and adaptation to metabolic stress. The pronounced metabolic dependence on PLD1 identifies it as a promising therapeutic target in SCC, and PLD1 inhibition may effectively exploit metabolic vulnerabilities unique to this tumor subtype.", "source_company": "Asan Medical Center, University of Ulsan College of Medicine", "source_org_type": "医院", "row_number": 1163, "target_meta": "PLD1", "MOA_meta": "抑制剂"}, {"drug_name": "tumor-derived vaccine expressing OX-40L and 4-1BBL", "company": "Brazilian Biosciences National Laboratory, Brazilian Center for Research in Energy and Materials", "org_type": "研究机构", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 45.5, "institution_score": 35, "track_score": 65, "milestone_score": 35, "field_heat_score": 50, "bonus_score": 0, "brief_reason": "该疫苗通过工程化TNBC细胞表达OX-40L和4-1BBL增强T细胞共刺激，但靶点未明确披露，仅为肿瘤来源细胞疫苗。机构为巴西研究机构非头部药企，处于体外验证阶段，整体开发里程碑较早期导致总分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9440", "id": "Q57M_5wBZznHJdnt_W7O", "source_drug_name": "tumor-derived vaccine expressing OX-40L and 4-1BBL", "title": "Exploring immunomodulatory tumor-derived vaccines targeting triple negative breast cancer cells", "abstract_text": "Breast cancer remains a major public health concern and is the leading cause of cancer-related deaths among women. Triple-negative breast cancer (TNBC) is the subtype with the poorest prognosis, and due to its phenotypic characteristics, no effective treatment is currently available for most diagnosed patients. This underscores the urgent need for novel therapeutic strategies. In this project, we explore antitumor vaccines generated from genetically modified TNBC cells expressing the immunomodulatory ligands TNFSF 4-1BBL and OX-40L. TNFSF ligands have the ability to costimulate T cells, enhancing their activation and proliferation. Previous studies from our group demonstrated that such vaccine combinations can increase T-cell proliferation, boost interferon-gamma production, inhibit regulatory T cells, and enhance T cell-mediated antitumor cytotoxicity, leading to a long term antitumor immunity and preventing tumor recurrence in cured and rechallenged animal models. Here, we generated antitumor vaccines derived from human TNBC cells, which were obtained after neoadjuvant chemotherapy from a patient sample provided by the CAISM-UNICAMP biobank. These cells were genetically engineered to express OX-40L and 4-1BBL, and the resulting tumor cell-based vaccines were evaluated in vitro for their antitumor potential. We observed that the vaccines enhanced immune responses in T lymphocytes from both autologous and allogeneic TNBC vaccines. Experimental assays confirmed that these tumor-derived vaccines induced elevated production of immunomodulatory cytokines and improved the antitumor T cell-mediated cytotoxicity. Our findings support the potential of this strategy as a promising immunotherapy approach for TNBC.\nEthical approval CAAE: 08897219.9.0000.5404\nSupported by CNPq 308403/2022-3, and FAPESP 2023/12245-0", "source_company": "Brazilian Biosciences National Laboratory, Brazilian Center for Research in Energy and Materials", "source_org_type": "研究机构", "row_number": 1171, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "TJM-2010", "company": "University of New Mexico Health Sciences Center", "org_type": "医院", "target": "MyD88", "modality": "inhibitor", "importance_level": "低", "total_score": 45.5, "institution_score": 30, "track_score": 75, "milestone_score": 40, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "TJM-2010为MyD88小分子抑制剂，用于探索其在TLR4/TLR9驱动的卵巢癌免疫治疗中的作用，阻断MyD88降低疗效表明其信号对抗肿瘤免疫重要。机构为大学医院非商业公司、仅为preclinical工具化合物研究无明确开发里程碑导致总体评分较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9700", "id": "c57M_5wBZznHJdnt_W7P", "source_drug_name": "TJM-2010", "title": "Investigating MyD88 and NLRP3 pathway modulation in a TLR4 and TLR9 driven immunotherapy in a murine model of ovarian cancer", "abstract_text": "Ovarian cancer remains one of the most devastating gynecologic malignancies, partly due to an immunosuppressive tumor microenvironment (TME) that limits immunotherapy efficacy. Our previous work showed that syngeneic cancer cell-based immune therapy containing monophosphoryl lipid A (TLR4 agonist) and CpG (TLR9 agonist) stimulates cancer-specific immune responses. Both receptors signal through MyD88 to activate NF-κB and pro-inflammatory cytokine production. These pathways also intersect with the NLRP3 inflammasome, which amplifies inflammation through IL-1β and IL-18. Controlled activation may enhance antitumor immunity, whereas dysregulated inflammasome signaling can promote chronic inflammation and immune suppression. Understanding how MyD88 and NLRP3 shape vaccine efficacy is therefore essential.This study evaluates how inhibition of MyD88 and NLRP3 affects the therapeutic efficacy of our ovarian cancer immune therapy. FVB mice bearing ovarian tumors received TLR-agonist silicified cancer cell immunotherapy with or without the NLRP3 inhibitor MCC950 (10 mg/kg) or the MyD88 inhibitor TJM-2010 (50 mg/kg). Inhibitors were administered around each immune-therapy dose. Ascitic immune cells were analyzed by spectral flow cytometry to assess immune subsets and activation markers.Blockade of the NLRP3 pathway accelerated ovarian cancer growth, while TLR-agonist immune therapy blocked tumor progression and cleared existing tumors. NLRP3 inhibition reduced therapeutic efficacy, tumor size decreased but complete clearance was not achieved. On Day 12, the immune-therapy group showed a significant reduction in tumor burden compared to PBS (p = 0.0034). The immune-therapy + NLRP3-inhibited group also differed from PBS but with diminished benefit (p = 0.0091). By Day 16, both BR5 immune-therapy and BR5 + inhibitor groups showed highly significant reductions in tumor burden compared to PBS (p < 0.0001).These findings demonstrate that NLRP3 signaling contributes critically to TLR4/TLR9-mediated antitumor responses. Ongoing studies will clarify how MyD88 and NLRP3 coordinate innate immune activation and guide future combination strategies to enhance immunity and overcome suppression within the ovarian TME.\nAI Disclosure:ChatGPT was used to assist with editing and wording of this abstract. All scientific content, study design, and interpretation were generated and verified by the authors.", "source_company": "University of New Mexico Health Sciences Center", "source_org_type": "医院", "row_number": 1199, "target_meta": "MyD88", "MOA_meta": "抑制剂"}, {"drug_name": "anti-PD-L1", "company": "University of Chicago", "org_type": "大学", "target": "PD-L1", "modality": "inhibitor", "importance_level": "低", "total_score": 45.5, "institution_score": 35, "track_score": 75, "milestone_score": 30, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "研究涉及anti-PD-L1抗体联合CD40激动剂在鳞癌中重塑中性粒细胞抗肿瘤活性，但靶点为经典PD-L1，机制属于联合治疗背景而非新药开发。机构为大学，开发阶段为机制研究，无明确里程碑进展，导致总分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1332", "id": "e57M_5wBZznHJdnt_W7P", "source_drug_name": "anti-PD-L1", "title": "Tumor stem cells reprogram neutrophils to establish a protective niche", "abstract_text": "The heterogeneous nature of tumor-associated neutrophils (TANs) has been recognized, but how different cell states of TANs emerge, evolve, distribute, and impact cancer immunotherapy efficacy remain elusive. Using single-cell RNA sequencing, spatial transcriptomics, and genetic manipulations, we show that anti-PDL1 + CD40 agonist immunotherapy can induce interferon responses in TANs, allowing them to regain antitumor activities in squamous cell carcinomas (SCC). In contrast, TANs residing at the tumor-stroma interface can preserve their immune suppressive state. Importantly, we identify a group of SOX2 High tumor-initiating stem cells (tSCs) at the tumor-stroma interface that upregulate fatty acid desaturase 1 (Fads1) to produce arachidonic acid (AA). This tSC-specific pathway enhances the prostaglandin E2 (PGE2 ) signaling in TANs, which can disrupt the interferon response and prevent the interferon-induced anti-tumor functions in TANs. By fine-tuning the plasticity of neutrophils, tSCs shape neutrophil heterogeneity and sculpt a protective micro-niche to survive from immunotherapy and drive cancer relapse.", "source_company": "University of Chicago", "source_org_type": "大学", "row_number": 1205, "target_meta": "PDL1", "MOA_meta": "抑制剂"}, {"drug_name": "anti-CTLA4", "company": "Cornell University", "org_type": "大学", "target": "CTLA4", "modality": "inhibitor", "importance_level": "低", "total_score": 45.3, "institution_score": 25, "track_score": 75, "milestone_score": 35, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "anti-CTLA4为经典免疫检查点抑制剂，靶向CTLA4，在TNBC中针对CD73缺失的间质型肿瘤显示CD4+ T细胞依赖的敏感性机制，但研究来自大学机构且处于preclinical探索阶段，无明确药物开发进展。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3697", "id": "qFXM_5wBX1NQZOEH-LG6", "source_drug_name": "anti-CTLA4", "title": "Understanding the mechanism by which CD4+ T cells sensitize mesenchymal CD73-deficient tumors to anti-CTLA4 immune checkpoint blockade therapy", "abstract_text": "Triple-Negative Breast Cancer (TNBC) is a highly aggressive disease with poor patient outcomes due to its resistance to chemotherapy and immunotherapy. Despite its efficacy in Melanoma and Lung carcinoma, immune checkpoint blockade (ICB) therapy is only effective in a small minority of TNBC patients. Epithelial-to-Mesenchymal Transition (EMT) is a key driver of malignant progression leading to greater metastatic potential and an immunosuppressive tumor microenvironment, driving resistance to therapies. Our previous results demonstrate that epithelial tumors respond to anti-CTLA4 therapy while mesenchymal tumors are resistant. Strikingly, knockout of CD73 in mesenchymal tumors results in complete sensitization to anti-CTLA4 treatment but not anti-PD1 therapy, the more clinically used treatment. Using our preclinical mouse models together with immunofluorescence staining, we observed that CD73-deficient tumors display increased infiltration of CD4+ and CD8+ T cells upon anti-CTLA4 treatment relative to non-responding controls. Most notably, while CD73 deficient tumors continued to respond to anti-CTLA4 treatment without CD8+ T cells, they failed to respond in the absence of CD4+ T cells. However, the mechanisms by which CD4+ T cells facilitate the elimination of mesenchymal tumors remain unknown. Preliminary results demonstrate that cytotoxic CD4+ T cells play a crucial role in potentiating the response of CD73-deficient tumors to anti-CTLA4. Moreover, tumors contain plastic CD4+ T cell subsets that reduce immune suppression under anti-CTLA4 treatment while promoting immune suppression under anti-PD1 treatment. These results reveal that CD4+ T cells can specifically target lethal mesenchymal cancer cells in response to anti-CTLA4 but not anti-PD1 therapy. Future work is aimed at understanding whether CD4+ T cells eliminate tumors via direct interactions with cancer cells or through indirect activation of other immune cells. Given the inefficacy of anti-PD1 therapy in TNBC clinical trials, characterizing the CD4+ T cell response to anti-CTLA4 provides a mechanistic basis for leveraging its therapeutic potential.", "source_company": "Cornell University", "source_org_type": "大学", "row_number": 431, "target_meta": "CTLA4", "MOA_meta": "抑制剂"}, {"drug_name": "CEA-specific CAR-NK cells", "company": "Candiolo Cancer Institute", "org_type": "研究机构", "target": "CEA", "modality": "CAR", "importance_level": "低", "total_score": 45.2, "institution_score": 25, "track_score": 75, "milestone_score": 45, "field_heat_score": 60, "bonus_score": 2, "brief_reason": "CEA靶向CAR-NK细胞针对结直肠癌，CAR-NK属于细胞治疗热门赛道但CEA非高热度靶点；机构为研究机构而非头部药企，处于优化参考CAR和早期平台工程的preclinical阶段，无明确临床里程碑。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3681", "id": "LZ7M_5wBZznHJdnt_W7O", "source_drug_name": "CEA-specific CAR-NK cells", "title": "Improving effector cells for CAR-NK immunotherapy against colorectal cancer", "abstract_text": "Chimeric Antigen Receptor (CAR)-based immunotherapy targeting carcinoembryonic antigen (CEA) represents a promising strategy for the treatment of colorectal cancer (CRC), a leading cause of cancer-related mortality worldwide. With respect to CAR-T cells, whose activity against solid tumors is limited by significant side effects, CAR-NK cells represent a potentially safer alternative, offering reduced toxicity while maintaining effective anti-tumor activity. We therefore worked at developing and optimizing CEA-specific CAR-NK cells against CRC, along three research lines: (i) selection and validation of a reference CEA CAR in the NK-92 model; (ii) further engineering of CEA.CAR-NK-92 cells with interleukins, and (iii) exploration of additional NK effector types. To select the reference CEA CAR construct, second generation CARs based on two scFvs with different affinities (hMN-14 and BW431/26, respectively higher and lower affinity) were constructed. Stable NK-92 clones were generated for each construct (higher affinity: NK-92.F3 clone; lower affinity: NK-92.G8 clone) and functionally characterized. In vitro, the NK-92.F3 clone exhibited stronger killing activity against CEA-positive CRC cells. In vivo, in NOD/Scid mice bearing CEA+ CRC xenografts, the two clones displayed comparable activity, both significantly reducing tumor progression and confirming their therapeutic potential. Considering the higher affinity and the better in vitro performances, the hMN-14-based CAR was selected as the reference CAR for subsequent evolutions of the NK platform. To enhance CAR-NK-92 performances, wild-type NK-92 and NK-92.F3 cells were engineered to constitutively express different interleukins. Functional assays demonstrated that specific interleukin expression markedly increased cytotoxicity and activation, highlighting cytokine engineering as an effective strategy to potentiate CAR-NK activity. To overcome the major intrinsic limitation of NK-92 cells, i.e. the need for irradiation before infusion, we investigated induced pluripotent stem cell (iPSC)-derived NK cells (iNKs) as a renewable and clinically scalable alternative NK source. Four iPSC-to-NK differentiation protocols were compared, three based on 3D embryoid body intermediates and one on 2D monolayer. Of these, one 3D and the 2D protocol proved more reliable. iPSC cells were then transduced with the reference CEA CAR, cloned, differentiated into NK and validated for functionality and cytotoxic performances. In conclusion, this work identified a robust reference CEA-CAR construct and established two complementary strategies, cytokine engineering to enhance effector function and iPSC-derived NK cell generation to overcome NK-92 limitations, providing a foundation for the development of safer, scalable, and next-generation CAR-NK therapies for colorectal cancer.", "source_company": "Candiolo Cancer Institute", "source_org_type": "研究机构", "row_number": 96, "target_meta": "CEACAM5", "MOA_meta": "其他"}, {"drug_name": "GW-833972A", "company": "Academia Sinica", "org_type": "研究机构", "target": "BMAL2", "modality": "inhibitor", "importance_level": "低", "total_score": 45.2, "institution_score": 35, "track_score": 55, "milestone_score": 45, "field_heat_score": 50, "bonus_score": 2, "brief_reason": "GW-833972A为BMAL2小分子抑制剂，通过诱导蛋白降解抑制同源重组DNA修复，在卵巢透明细胞癌中显示体内抑瘤效果。机构为研究机构且仅处preclinical虚拟筛选阶段，赛道非热门导致综合评分较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4711", "id": "dJ7M_5wBZznHJdnt_W3O", "source_drug_name": "GW-833972A", "title": "BMAL2 maintains DNA integrity via regulating homologous recombination to promote ovarian clear cell carcinoma tumorigenesis", "abstract_text": "Ovarian cancer is the most lethal gynecologic malignancy worldwide. Among its subtypes, ovarian clear cell carcinoma (OCCC) is characterized by its intrinsic chemoresistance, poor prognosis, and lack of effective therapies. To date, only ARID1A mutant OCCC has shown modest sensitivity to PARP inhibitors, highlighting the urgent need for novel therapeutic targets. Here, we identified BMAL2, a circadian transcription as a critical DNA integrity regulator in OCCC cells. BMAL2 depletion downregulated RAD51, impaired homologous recombination-mediated DNA repair thereby inhibited cell survival and tumor growth. To pharmacologically target BMAL2, we performed structure-based virtual screening and identified GW-833972A as a small-molecule inhibitor that effectively bound and degraded BMAL2 protein. Mechanistically, GW-833972A mediated BMAL2 degradation impaired DNA repair and suppressed tumor growth in vivo. Collectively, these findings reveal the critical oncogenic role of BMAL2 in OCCC and demonstrate that BMAL2 inhibition offers a promising therapeutic strategy for this chemoresistant cancer.", "source_company": "Academia Sinica", "source_org_type": "研究机构", "row_number": 1028, "target_meta": "not available", "MOA_meta": "抑制剂"}, {"drug_name": "pertuzumab deruxtecan", "company": "Kawasaki Medical School", "org_type": "大学", "target": "HER2", "modality": "ADC", "importance_level": "低", "total_score": 45, "institution_score": 20, "track_score": 85, "milestone_score": 40, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "药品为HER2靶向ADC，在食管癌患者来源类器官中显示有效杀伤活性，但仅为大学机构的体外preclinical研究，未披露独立开发管线或临床进展。打分依据：大学机构分低、ADC+HER2赛道热门但非临床里程碑、领域对食管癌HER2 ADC有一定潜力但整体preclinical阶段热度有限。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6926", "id": "hp7M_5wBZznHJdnt_W7P", "source_drug_name": "pertuzumab deruxtecan", "title": "Establishment and characterization of novel patient-derived esophageal tumoroids with long term cultivability", "abstract_text": "Esophageal cancer, which includes esophageal squamous cell carcinoma (ESCC) and esophageal adenocarcinoma (EAC), is a highly aggressive malignancy and ranks as the eleventh most prevalent cancer worldwide. Despite therapeutic progress, the 5-year survival rate remains poor. To enable the development of new treatment strategies, robust preclinical models of esophageal carcinoma are essential. Recent progress has enabled three-dimensional (3D) organoid systems generated from adult or pluripotent stem cells. Such organoids faithfully reproduce the architecture and functions of the tissue of origin and have been established from multiple human sources, including patient-derived tumors of the colon, prostate, breast, pancreas, esophagus, bladder, and liver. In this study, we generated three human esophageal cancer organoids from surgical specimens and maintained long-term cultures exceeding 12 months. All lines also met a practical durability benchmark—continuous growth for ≥3 months or ≥10 serial passages—thereby enabling consistent pharmacologic testing and cross-batch reproducibility. Two organoids originated from ESCC, and one from EAC that arose in Barrett’s esophagus. Whole-exome sequencing showed that these organoids preserved the genetic alterations present in the corresponding primary tumors. In parallel, patient-derived xenografts recapitulated the histopathology of the original esophageal cancers. Comprehensive assessments, including copy-number profiling and immunohistochemistry, demonstrated HER2 expression with amplification and HER3 expression with mutation in the EAC-derived organoid. Notably, HER2-directed antibody-drug conjugates (ADCs), including trastuzumab deruxtecan (T-DXd) and pertuzumab deruxtecan (P-DXd), effectively reduced tumor cell viability in these organoids. The successful creation of esophageal organoids with durable cultivability enables reproducible foundational studies, including drug-sensitivity testing, which are critical for advancing personalized therapy and rational treatment design. This work provides actionable resources for clinicians and researchers seeking to improve therapeutic approaches for esophageal cancer.", "source_company": "Kawasaki Medical School", "source_org_type": "大学", "row_number": 103, "target_meta": "HER2", "MOA_meta": "抗体偶联药物"}, {"drug_name": "anti-PD-1", "company": "Loyola University Chicago Stritch School of Medicine", "org_type": "大学", "target": "PD-1", "modality": "inhibitor", "importance_level": "低", "total_score": 45, "institution_score": 25, "track_score": 75, "milestone_score": 40, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "anti-PD-1为经典免疫检查点抑制剂，靶向PD-1；但本条为大学学术研究，主要探讨衰老微环境对GBM中anti-PD-1疗效的影响并结合senolytics，未体现药物自身新开发或里程碑进展，机构非药企导致总体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10495", "id": "8lXM_5wBX1NQZOEH-LC5", "source_drug_name": "anti-PD-1", "title": "Age-dependent neuro-immune changes in glioblastoma shape therapeutic response and reveal senescent microglia as a targetable vulnerability", "abstract_text": "Background: Glioblastoma (GBM) is the most common aggressive primary brain tumor, with a median overall survival (OS) of ≈15-18 months despite standard of care (SOC). Aging is a major negative prognostic factor, with older adults showing worse OS. Senescent cells accumulate with age and contribute to poorer outcomes. Senolytics clear senescent cells and may improve responses in older hosts. While tumor-intrinsic molecular features appear age-independent, the aging brain microenvironment impact on GBM progression and immunity remains unclear.\nObjective: To define age-associated senescence patterns in tumor core and peritumoral (PT) brain in GBM patients and mouse models and assess whether senolytic enhance treatment responses in aged syngeneic and humanized GBM models.\nMethods: MRI-guided tumor core and PT biopsies from GBM patients (<65 vs. ≥65) underwent transcriptomic and single-cell analyses to assess age-related neuro-immune and senescence changes. Senescence across tumor regions was examined in young (7-9 weeks) and aged (97-104 weeks) C57BL/6 and INK-ATTAC mice with intracranial SB28 tumors (n=5/group). Flow cytometry quantified β-gal+ senescent populations among neurons, astrocytes, oligodendrocytes, microglia, and immune infiltrates from tumor core and extratumoral brain. Mice received brain radiation, anti-PD-1, and IDO enzyme inhibition, alone ± senolytics (dasatinib+quercetin) or AP compound-induced clearance p16INK4A+ senescent cells. A human GBM aging model was developed by depleting CD4+, CD8+, CD19+, and NK1.1+ cells in young and aged C57BL/6 mice, prior to patient-derived GBM43 (PDX) intracranial engraftment, followed by SOC radiotherapy + temozolomide ± senolytics.\nResults: Transcriptomic profiling showed minimal age-related changes in tumor core but marked alterations in older PT tissues. Aged PT microglia exhibited a senescent phenotype with an upregulation of senescence-associated secretory phenotype (SASP) genes. Senolytics or AP compound significantly reduced extratumoral β-gal+ microglia and synergized with radio-immunotherapy to extend OS in aged mice (p<0.05). In the humanized immunodepleted GBM43 PDX model, young and aged mice developed tumors, with faster mortality in older hosts. Therapeutic responses to SOC ± senolytics are ongoing.\nConclusions: The PT brain is a key site of age-dependent immune dysfunction in GBM. Senescent microglia may create an immunosuppressive niche that limits the immunotherapy efficacy in older adults. Senolytics may restore treatment efficacy and improve outcomes in older GBM hosts. We developed a novel immunodepleted GBM PDX model to mechanistically evaluate the role of aging in human tumor progression and therapy resistance. Keywords: glioblastoma, peritumoral brain, aging, immunotherapy, senescence, microglia", "source_company": "Loyola University Chicago Stritch School of Medicine", "source_org_type": "大学", "row_number": 298, "target_meta": "PD1", "MOA_meta": "抑制剂"}, {"drug_name": "anti-PD-1", "company": "University of Pennsylvania", "org_type": "大学", "target": "PD-1", "modality": "inhibitor", "importance_level": "低", "total_score": 45, "institution_score": 40, "track_score": 85, "milestone_score": 20, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "药物为anti-PD-1，靶点PD-1，属于经典免疫检查点抑制剂，但摘要无任何具体内容，仅为标题描述机制。大学机构非商业研发主体，得分较低；赛道虽热门但无新进展或里程碑信息，导致整体重要性低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/2064", "id": "JVXM_5wBX1NQZOEH-LG5", "source_drug_name": "anti-PD-1", "title": "Immunopharmacology of anti-PD-1 and reinvigoration of exhausted CD8 T cells", "abstract_text": "There is no abstract associated with this presentation.", "source_company": "University of Pennsylvania", "source_org_type": "大学", "row_number": 335, "target_meta": "PD1", "MOA_meta": "抑制剂"}, {"drug_name": "metabolism-responsive self-assembling SMDC", "company": "Institute of Materia Medica, Chinese Academy of Medical Sciences and Peking Union Medical College", "org_type": "研究机构", "target": "未披露", "modality": "SMDC", "importance_level": "低", "total_score": 45, "institution_score": 45, "track_score": 70, "milestone_score": 20, "field_heat_score": 50, "bonus_score": 0, "brief_reason": "药物为代谢响应型自组装小分子药物偶联物（SMDC），靶点未披露，仅为preclinical概念性研究。机构为国内研究机构非头部企业、摘要被禁未显示具体数据或里程碑、赛道虽涉及靶向递送但非热门modality且缺乏明确亮点，导致总体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11300", "id": "WVXM_5wBX1NQZOEH-LG5", "source_drug_name": "metabolism-responsive self-assembling SMDC", "title": "A metabolism-responsive self-assembling SMDC for dual-targeting therapy of refractory solid tumors", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Institute of Materia Medica, Chinese Academy of Medical Sciences and Peking Union Medical College", "source_org_type": "研究机构", "row_number": 374, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "Inflachromene", "company": "Keck School of Medicine of USC", "org_type": "大学", "target": "HMGB2", "modality": "inhibitor", "importance_level": "低", "total_score": 45, "institution_score": 30, "track_score": 60, "milestone_score": 50, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "Inflachromene为HMGB2小分子抑制剂，用于探索其在胶质母细胞瘤干细胞放射抗性中的作用，机制为抑制HMGB2。机构为大学非商业研发，处于preclinical机制研究阶段，无显著开发里程碑，综合热度中等但重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9335", "id": "EFXM_5wBX1NQZOEH-LO6", "source_drug_name": "Inflachromene", "title": "HMGB2-mediated radioresistance of glioblastoma stem cells", "abstract_text": "Glioblastoma (GBM) is the most common and deadly adult central nervous system cancer. Despite surgical resection combined with DNA-damaging radiation and chemotherapy, GBM almost invariably recurs, becoming more resistant to radiation. To investigate the drivers of this radioresistance, we conducted a knockout radiosensitization screen and identified the High Mobility Group B2 (HMGB2) protein as a potential contributor. To elucidate HMGB2’s role in GBM radioresistance, we performed viability, clonogenic survival, extreme limiting dilution (ELDA), and deletion mutant assays on patient-derived glioblastoma stem cells (GSCs) treated with a combination of radiotherapy (RT) and either HMGB2 knockdown or inhibition using Inflachromene (ICM), a small molecule inhibitor of HMGB2. Without radiation, ICM showed IC-50 values ranging from 8.43 µM to 10 µM across three GSC lines. Both ICM treatment and HMGB2 knockdown significantly reduced neurosphere formation compared to cultures treated with only RT and vehicle. Knockdown of endogenous HMGB2 combined with overexpression of an Acidic Tail-deleted HMGB2 mutant produced distinct puncta under fluorescence microscopy, unlike other deletion mutants. These findings implicate HMGB2 in GBM radioresistance and suggest that the Acidic Tail region mediates chromatin binding, possibly playing a role in HMGB2’s mechanism of action. Together, these results provide a foundation for clarifying HMGB2’s role in GBM biology and it’s potential relevance to improving therapeutic response.", "source_company": "Keck School of Medicine of USC", "source_org_type": "大学", "row_number": 661, "target_meta": "HMGB2", "MOA_meta": "抑制剂"}, {"drug_name": "BCI", "company": "UT Health Houston", "org_type": "医院", "target": "DUSP1", "modality": "inhibitor", "importance_level": "低", "total_score": 45, "institution_score": 30, "track_score": 65, "milestone_score": 50, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "BCI为DUSP1抑制剂（小分子抑制剂），通过抑制DUSP1激活ROS依赖的JNK/p38和ER应激通路，增强NET对¹⁷⁷Lu-DOTATATE的敏感性。机构为医院/大学类型非商业研发、处于preclinical阶段且仅体外+PDX模型、赛道为DUSP1靶点非热门导致总分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1925", "id": "KFXM_5wBX1NQZOEH-LO6", "source_drug_name": "BCI", "title": "Targeting DUSP1 overcomes resistance to ¹⁷⁷Lu-DOTATATE in neuroendocrine tumors", "abstract_text": "Background: Neuroendocrine tumors (NETs) often present as metastatic or unresectable disease, and while ¹⁷⁷Lu-DOTATATE PRRT benefits SSTR2-positive patients, its modest response rate highlights the need for improved combinations. DUSP1, a MAPK phosphatase regulating JNK/p38, is elevated in multiple cancers, yet its role in NETs is unknown. Given the contribution of MAPK signaling to therapy resistance, we hypothesized that DUSP1 inhibition enhances NET sensitivity to ¹⁷⁷Lu-DOTATATE.\nMaterials and Methods: We compared DUSP1 mRNA levels in primary versus metastatic NETs using public transcriptomic datasets and assessed DUSP1 protein across NET cell lines and two PDX models by Western blot. Functional studies with the DUSP1 inhibitor BCI measured viability, clonogenic survival, apoptosis, mitochondrial depolarization, ROS and MAPK activation, with RNA-seq defining transcriptional changes. Rescue experiments used CC90001, ISRIB, NAC, DUSP1 overexpression, and the JNK1-K55R mutant. Synergy with PRRT was evaluated by combining BCI with sub-lethal ¹⁷⁷Lu-DOTATATE.\nResults: Transcriptomic profiling showed elevated DUSP1 in lymph-node metastases versus primary NETs, and DUSP1 protein was highly expressed across NET cell lines and PDX models. BCI (1-2.5 μM) markedly reduced viability and clonogenic survival (~80% at 1 μM) and induced apoptosis (cleaved PARP ~6-fold, caspase-3/7 ~4-fold, ΔΨm loss ~2-fold). RNA-seq and Western blotting confirmed strong activation of pro-apoptotic JNK1/2 and p38. JNK inhibition, the JNK1-K55R mutant, and DUSP1 overexpression each rescued cells, whereas DUSP1 knockdown induced apoptosis—establishing DUSP1 as a key NET survival factor. RNA-seq also revealed ER-stress activation (XBP1s, ATF4, CHOP). ISRIB blocked ER stress and rescued cells, while NAC suppressed ROS, prevented MAPK/ER-stress activation, and fully rescued cells, indicating that DUSP1 inhibition triggers a ROS-dependent cascade converging on JNK and ER-stress pathways. Combining BCI with ¹⁷⁷Lu-DOTATATE produced strong synergy (CI < 0.5) with enhanced apoptosis. JNK inhibition and ISRIB each rescued combination-induced apoptosis (~60% and ~40%), showing that both pathways are required for PRRT sensitization.\nConclusion: DUSP1 is an actionable therapeutic vulnerability in NETs. Its inhibition induces ROS-driven activation of pro-apoptotic MAPK and ER-stress pathways, potentiating ¹⁷⁷Lu-DOTATATE. These findings provide preclinical support for DUSP1-targeted combination strategies, with ongoing in vivo studies needed to advance this approach toward clinical translation.", "source_company": "UT Health Houston", "source_org_type": "医院", "row_number": 678, "target_meta": "DUSP1", "MOA_meta": "抑制剂"}, {"drug_name": "anti-CTLA-4 antibody", "company": "Affiliated Sanming First Hospital of Fujian Medical University", "org_type": "医院", "target": "CTLA-4", "modality": "inhibitor", "importance_level": "低", "total_score": 45, "institution_score": 25, "track_score": 75, "milestone_score": 40, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "药物为anti-CTLA-4抗体（已验证的经典免疫检查点靶点），但研究机构为地方医院，主要探讨高温治疗时机对联合anti-CTLA-4疗效的调控而非药物自身开发，缺乏药物创新性里程碑。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5322", "id": "z57M_5wBZznHJdnt_W3O", "source_drug_name": "anti-CTLA-4 antibody", "title": "Chronotherapy of hyperthermia: Circadian rhythm governs HSP expression and modulates anti-tumor immunity", "abstract_text": "Background: Heat shock protein (HSP) expression is a key mechanism underlying hyperthermia-induced anti-tumor immunity. However, whether HSP expression exhibits circadian rhythmicity and how this impacts therapeutic efficacy remains unclear.\nMethods: Murine tumor models received localized hyperthermia at different times of day (specifically comparing afternoon and nighttime). Core circadian clock proteins (e.g., Bmal1 or Clock) were genetically ablated. Tumor tissues were analyzed for: (1) HSP expression levels post-hyperthermia; (2) release of damage-associated molecular patterns (DAMPs), including HMGB1 and ATP; (3) infiltration of CD8+ T cells. The effect of hyperthermia timing on treatment efficacy, both alone and in combination with anti-CTLA-4 antibody, was evaluated.\nResults: HSP expression induced by hyperthermia showed significant circadian variation: it was highest when hyperthermia was administered in the afternoon and lowest when administered at nighttime. Genetic ablation of core circadian clock proteins abolished this time-dependent difference in HSP expression, confirming the critical regulatory role of the biological clock. Compared to afternoon hyperthermia, nighttime hyperthermia triggered significantly greater release of immunogenic DAMPs (HMGB1, ATP) from tumor tissue and induced markedly enhanced infiltration of CD8+ T cells.Crucially, nighttime hyperthermia demonstrated a significantly stronger synergistic anti-tumor effect when combined with anti-CTLA-4 immune checkpoint blockade therapy.\nConclusion: The circadian rhythm profoundly influences the immunogenic effects of hyperthermia by regulating HSP expression. Although inducing lower HSP levels, nighttime hyperthermia is more effective at releasing immunogenic DAMPs (HMGB1, ATP), promoting CD8+ T cell infiltration, and potently enhancing the efficacy of anti-CTLA-4 therapy. This study identifies timing of hyperthermia administration (specifically nighttime) as a critical factor for optimizing immunogenic cell death and augmenting the effectiveness of combined immunotherapy.", "source_company": "Affiliated Sanming First Hospital of Fujian Medical University", "source_org_type": "医院", "row_number": 1098, "target_meta": "CTLA4", "MOA_meta": "抑制剂"}, {"drug_name": "DDR2-CAR macrophages", "company": "Guangzhou Medical University", "org_type": "大学", "target": "DDR2", "modality": "CAR", "importance_level": "低", "total_score": 44.8, "institution_score": 25, "track_score": 75, "milestone_score": 35, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "DDR2-CAR-M通过靶向DDR2重编程CAF和TME，将免疫冷肿瘤转为热肿瘤并促进血管正常化。大学机构+仅动物模型阶段导致总体分较低，但CAR+实体瘤TME改造赛道仍有一定热度。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9611", "id": "W57M_5wBZznHJdnt_W3O", "source_drug_name": "DDR2-CAR macrophages", "title": "DDR2-CAR macrophages reprogram the tumor microenvironment and normalize vasculature to potentiate antitumor immunity", "abstract_text": "The immunosuppressive extracellular matrix (ECM) of solid tumors is a major barrier to effective antitumor immunity, primarily by fostering immune exclusion. Targeting cancer-associated fibroblasts (CAFs), particularly via discoidin domain receptor 2 (DDR2), has emerged as a strategic avenue to overcome this barrier. Here, we engineered DDR2-targeted chimeric antigen receptor macrophages (DDR2-CAR-M) to leverage macrophage infiltration capacity and disrupt ECM-mediated immunosuppression. In vitro studies demonstrated robust DDR2-CAR adenoviral transduction efficiency (>95%) in primary mouse bone marrow-derived macrophages, with flow cytometry confirming M1 polarization within 48 hours post-transduction. In murine models, immunofluorescence and in vivo imaging revealed elevated DDR2 expression in the ECM of LLC subcutaneous tumor, MC-38 subcutaneous tumor, and U87MG orthotopic glioblastoma model. Tumor growth curves demonstrated significant suppression of lung and colorectal cancers following DDR2-CAR-M combination therapy. Mechanistic investigations using single-cell RNA sequencing, pathological analysis, and flow cytometry indicated a marked activation of immune-related signaling pathways in the CAR-M treatment group, characterized by a significant increase in CD8+ T cells and dendritic cells, suggesting that CAR-M-mediated targeting of CAFs can effectively convert immunologically \"cold\" tumors into \"hot\" ones. Furthermore, DDR2-CAR-M remodeled the tumor microenvironment by inhibiting aberrant angiogenesis and promoting vascular normalization, enhancing antigen presentation by macrophages, and promoting T-cell infiltration. These findings establish DDR2-CAR-M as a novel immunotherapeutic approach for solid tumors through stromal reprogramming and immune microenvironment optimization.", "source_company": "Guangzhou Medical University", "source_org_type": "大学", "row_number": 1013, "target_meta": "DDR2", "MOA_meta": "其他"}, {"drug_name": "r-AAV-Notch1D", "company": "LSU Health New Orleans", "org_type": "大学", "target": "Notch1", "modality": "other", "importance_level": "低", "total_score": 44.5, "institution_score": 25, "track_score": 65, "milestone_score": 45, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "药物为大学机构开发的rAAV载体编码可溶性Notch1 decoy，靶向阻断Notch信号以抑制TNBC肿瘤生长和癌干细胞。机构为非商业大学导致基础分低，Notch在TNBC有一定研究热度但非最热门靶点、仍处preclinical阶段且无突破性机制，综合重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5335", "id": "_FXM_5wBX1NQZOEH-LC5", "source_drug_name": "r-AAV-Notch1D", "title": "Targeting notch signaling in triple negative breast cancer with a novel adeno-associated virus-mediated therapy to enhance immunomodulation", "abstract_text": "Triple-negative breast cancer (TNBC) is a group of aggressive breast cancers with a higher mortality rate. TNBC patients have a higher rate of mortality due to metastasis or local recurrences, which are chemo- and radio-resistant. Notch signaling has emerged as an important factor in TNBC. There is strong evidence for Notch signaling involvement in TNBC. Recent studies suggest that Cancer Stem cells (CSCs) that emerge after chemotherapy or targeted agents in TNBC are often Notch-dependent. Notch inhibitors, including Gamma Secretase Inhibitors (GSIs), are quite effective in preclinical models of TNBC because they eliminate CSCs that are resistant to chemotherapy. Unfortunately, this approach has had minimal success in clinical trials due to its intestinal toxicity and adverse effects on immune cells. To avoid these toxicities, we aim to use a recombinant adeno-associated virus (r-AAV) vector encoding a soluble Notch1 decoy (r-AAV-Notch1D) to block Notch signaling intratumorally in TNBC. r-AAVs are non-replicating viruses and, therefore, are a safe platform for in vivo gene delivery. We found that r-AAV-GFP transduced both human and mouse TNBC cells. Our r-AAV constructs contain a C1QTNF3-derived collagen domain (CD) that facilitates the trimerization and stabilization of secreted fusion proteins. We purified these proteins using His-Tag affinity chromatography and found that they significantly reduced mammosphere growth in human TNBC cells and reduced Notch intracellular domain (NICD) expression. Intratumoral injections of the r-AAV-Notch1D virus significantly reduced syngeneic mouse TNBC tumor (C0321) growth and increased the tumor-infiltrating lymphocytes, including CD3 and CD8. Notably, the r-AAV-Notch1D virus significantly enhanced the efficacy of immunotherapy (a-PD1) in mediating the anti-tumor effect in the syngeneic TNBC mouse model. We performed RNA sequencing to identify tentative target(s) for r-AAV-Notch1D. We found that Hmox1, Timp3, Il33, Adam8, Ero1l, and Saa3 genes were upregulated, on the other hand Gm11408, Gm9844, Gm11407, Gm8430, Rnu3a, and Per1 genes were downregulated upon the treatment. From our Gene Ontology analysis, we found that r-AAV-Notch1D treatment enhanced hexosaminidase activity, carbohydrate catabolic process, covalent chromatin modification, histone modification, and histone acetylation. r-AAV-Notch1D treatment also altered several cellular pathways, including MicroRNAs in cancer, Ferroptosis, Porphyrin metabolism, Mineral absorption, and the Cytosolic DNA-sensing pathway. Given the diverse biological functions of these pathways, further study is warranted to elucidate their roles in TNBC. Overall, our findings indicate that the r-AAV-Notch1D virus is a promising approach for treating TNBC, alone or in combination with immunotherapy, and is a candidate for translational application.", "source_company": "LSU Health New Orleans", "source_org_type": "大学", "row_number": 306, "target_meta": "NOTCH1", "MOA_meta": "其他"}, {"drug_name": "TDIMER", "company": "Houston Methodist Research Institute", "org_type": "研究机构", "target": "iNOS", "modality": "inhibitor", "importance_level": "低", "total_score": 44.5, "institution_score": 35, "track_score": 45, "milestone_score": 55, "field_heat_score": 50, "bonus_score": 2, "brief_reason": "TDIMER为新型iNOS抑制剂，针对炎性乳腺癌，机制上优于LNMMA且安全性更好（无血压影响）。机构为研究机构非药企、赛道非热门、仍处早期preclinical阶段导致总体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5684", "id": "GFXM_5wBX1NQZOEH-LK6", "source_drug_name": "TDIMER", "title": "A novel iNOS inhibitor as a targeted therapeutic approach for inflammatory breast cancer", "abstract_text": "Nitric oxide (NO), generated by inducible nitric oxide synthase (iNOS), has been implicated in tumor progression, metastasis, and therapy resistance. Our completed phase Ib/II clinical trial in metastatic and locally advanced triple negative breast cancer showed that combination therapy with the pan NOS inhibitor LNMMA and standard chemotherapy elicits potent antitumor activity. Mechanistically, LNMMA targets the breast cancer stem cell (BCSCs) population enhancing their susceptibility to chemotherapy. We have developed a new iNOS inhibitor TDIMER co formulated with a calcium channel antagonist to mitigate the hemodynamic effects associated with systemic iNOS inhibition. We hypothesize that TDIMER can be effective for the treatment of inflammatory breast cancer (IBC), a rare and highly aggressive subtype with high recurrence rates and poor prognosis. In vitro studies were performed using SUM149 IBC cells. iNOS expression was confirmed by RT-qPCR and western blot. TDIMER efficacy was assessed, alone or with docetaxel, and compared to LNMMA, through cell proliferation, apoptosis and cell migration assays. BCSCs (CD44⁺/CD24⁻/low) were identified by flow cytometry after treatment with TDIMER or LNMMA in combination with docetaxel. In vivo studies using non-tumor bearing NSG mice were conducted to determine TDIMER dose toxicity and effect on blood pressure (BP). Mice received TDIMER (40 mg/kg oral gavage on day 1, 20 mg/kg oral gavage on days 2-5) or in combination with the calcium channel blocker amlodipine (10 mg/kg IP injection on days 1-5). Mice treated with PBS were used as control. BP was measured daily with BP-2000 (Visitech Systems). Animals were euthanized on day 5 for histopathological analysis and assessment of biochemical markers (ALT, AST, BUN) in serum samples. TDIMER treatment demonstrated superior efficacy over LNMMA, with a markedly lower IC₅₀ in SUM149 cells. TDIMER more effectively reduced cell viability, and delayed migration relative to LNMMA. Combination therapy with TDIMER and docetaxel induced the highest levels of apoptosis and reduced BCSCs, suggesting potent activity against chemo resistant tumor-initiating cells. In vivo toxicity studies demonstrated that TDIMER treatment did not produce histopathological alterations or significant elevations in serum ALT, AST, or BUN levels, confirming a favorable safety profile. Furthermore, no significant changes in BP were observed across experimental groups, underscoring TDIMER’s advantage in achieving potent iNOS inhibition without the need for coadministration of antihypertensive agents. Ongoing studies are aimed to elucidate the antitumor efficacy of TDIMER in xenograft mouse models of IBC. Overall, our findings support continued preclinical development of TDIMER as a novel iNOS targeted therapy for IBC patients.", "source_company": "Houston Methodist Research Institute", "source_org_type": "研究机构", "row_number": 506, "target_meta": "NOS2", "MOA_meta": "抑制剂"}, {"drug_name": "AA147", "company": "University of Arkansas for Medical Sciences", "org_type": "大学", "target": "ATF6", "modality": "small molecule", "importance_level": "低", "total_score": 44.5, "institution_score": 25, "track_score": 65, "milestone_score": 45, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "AA147为小分子ATF6激活剂，可通过上调抗肿瘤免疫调控基因增强ICB疗效，但仅限于preclinical小鼠黑色素瘤模型。大学机构+早期preclinical阶段导致总体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9454", "id": "VVXM_5wBX1NQZOEH-LK6", "source_drug_name": "AA147", "title": "Characterizing ATF6 activation-driven mechanisms improving ICB efficacy", "abstract_text": "Melanoma is the most fatal skin cancer and incidence continues to rise, particularly among young people. Among the current clinical standards of care for advanced melanoma, immune checkpoint blockade (ICB) therapy has been the most successful for improving the survival of melanoma patients. However, the benefits of ICB therapy are limited to a subset of melanoma patients, with only 50% of melanoma patients responding ICB due to primary resistance. Using a genetic model of activating transcription factor 6 (ATF6), our laboratory has found that constitutively active ATF6 improved ICB efficacy in multiple preclinical, ICB resistant mouse melanoma models and increased T cell mediated-killing (TCK) of melanoma tumor cells in vitro. As a translational strategy we used a previously reported small molecule ATF6 activator, AA147, and found an AA147-mediated increase in TCK in vitro and an improvement of ICB efficacy in preclinical ICB resistant subcutaneous and metastatic mouse melanoma models. To identify ATF6-dependent mechanisms improving anti-tumor immune response, we performed FactorPath (Active Motif) chromatin immunoprecipitation coupled with sequencing (ChIP-seq) to map the binding of FLAG-ATF6 at a genome-wide scale. We found that the constitutively active form of ATF6 binds to the promoter region of anti-tumor immune regulatory genes. In parallel with ChIP-seq findings, we found constitutively active ATF6 significantly upregulates the protein expressions of anti-tumor immune regulatory genes as determined through quantitative mass spectrometry. These findings indicate that ATF6 is a transcriptional regulator of anti-tumor immune regulatory genes in melanoma tumor cells and upregulation of these pathways leads to enhanced anti-tumor immune response and improved ICB efficacy.", "source_company": "University of Arkansas for Medical Sciences", "source_org_type": "大学", "row_number": 540, "target_meta": "ATF6", "MOA_meta": "其他"}, {"drug_name": "anti-PD-1", "company": "Soonchunhyang University Hospital Bucheon", "org_type": "医院", "target": "PD-1", "modality": "inhibitor", "importance_level": "低", "total_score": 44.5, "institution_score": 25, "track_score": 75, "milestone_score": 35, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "药物为anti-PD-1抑制剂，靶向PD-1；研究来自医院机构，属于ex vivo抗PD-1响应与Treg浸润及ARID1A状态的生物标志物探索，无新药开发里程碑，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10827", "id": "o1XM_5wBX1NQZOEH-LK6", "source_drug_name": "anti-PD-1", "title": "Effector regulatory T-cell infiltration, ARID1A status, and Ex Vivo anti-PD-1 response in ovarian clear cell carcinoma: Insights from a comparative high-grade serous ovarian cancer cohort", "abstract_text": "Recent trials suggest potential benefit of immune checkpoint blockade (ICB) in ovarian clear cell carcinoma (OCCC), but the immune contexture and biomarkers that modulate ICB response remain poorly understood. We characterized tumor-infiltrating lymphocytes (TILs) in OCCC and explored associations with clinical features, ex vivo anti-PD-1-based ICB responsiveness, and biomarker expression. Peripheral blood mononuclear cells (PBMCs) and TILs were obtained from patients with OCCC (n=55). Immune checkpoint receptor and transcription factor expression were analyzed by multicolor flow cytometry. TILs were stimulated ex vivo with anti-CD3 plus anti-PD-1 with or without anti-CTLA-4, and proliferation was assessed by T-cell division. HER2, ARID1A, and L1CAM expression were evaluated by immunohistochemistry on tumor tissue. Twenty of 55 patients had stage III/IV or recurrent disease, and most tumors were grade 3. Among evaluable tumors, 9/38 exhibited HER2 2+/3+, 24/41 showed loss of ARID1A, and 29/41 showed high L1CAM expression. In flow cytometric analysis, CD8 T cells and regulatory T cells (Tregs) were enriched in tumors compared with peripheral blood. CD8⁺ TILs showed a profoundly exhausted phenotype, with higher PD-1, CTLA-4, and TOX and lower TCF-1 expression than CD8⁺ T cells in blood, while tumor-reactive CD39⁺CD103⁺ CD8 TILs were also more enriched. Tregs exhibited highly suppressive features with increased immune checkpoint receptors, CD39, and CCR8, and effector Tregs (CD45RA⁻FoxP3high) were more abundant in stage III/IV or recurrent tumors than in stage I/II disease. In ex vivo assays, CD8 TILs from a subset of patients showed robust anti-PD-1-induced proliferation, and effector Treg frequency was inversely associated with anti-PD-1-induced CD8 T-cell reinvigoration. ARID1A-deficient tumors exhibited significantly lower effector Treg infiltration, whereas HER2 and L1CAM expression were not clearly associated with T-cell phenotypes or anti-PD-1 response. When compared with our previously reported cohort of advanced-stage high-grade serous ovarian cancer (HGSOC), the percentage of tumor-infiltrating Tregs, particularly 4-1BB⁺ Tregs, was lower in advanced/recurrent OCCC than in HGSOC. In conclusion, OCCC exhibits profound exhaustion of CD8 TILs alongside infiltration of highly suppressive Tregs. Effector Treg frequency was inversely associated with anti-PD-1-induced CD8 T-cell reinvigoration, and ARID1A loss may be linked to a tumor microenvironment more permissive to anti-PD-1-based immune checkpoint blockade. This hypothesis may help explain the high ICB response rate reported in OCCC compared with HGSOC and requires confirmation in larger clinical cohorts and mechanistic studies elucidating how ARID1A loss in OCCC reprograms the tumor immune microenvironment.", "source_company": "Soonchunhyang University Hospital Bucheon", "source_org_type": "医院", "row_number": 589, "target_meta": "PD1", "MOA_meta": "抑制剂"}, {"drug_name": "CDK4/6 inhibitors", "company": "Dan L Duncan Comprehensive Cancer Center", "org_type": "医院", "target": "CDK4/6", "modality": "inhibitor", "importance_level": "低", "total_score": 44.5, "institution_score": 25, "track_score": 75, "milestone_score": 35, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "摘要聚焦CDK4/6抑制剂在ER+/HER2-乳腺癌中的耐药机制研究，靶点为经典细胞周期CDK4/6，但机构为医院/学术中心且无新药开发信息。耐药生物标志物探索有一定学术价值，但缺乏药物研发里程碑，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1189", "id": "1VXM_5wBX1NQZOEH-LK6", "source_drug_name": "CDK4/6 inhibitors", "title": "MCM2 and the origin licensing complex: A putative node of ER+/HER2- breast cancer therapy resistance", "abstract_text": "Background: The use of CDK4/6 inhibitors (CDK4/6i) in combination with endocrine therapy (ET) has revolutionized treatment practices for advanced and high-risk ER+/HER2- breast cancer (BC) via effective inhibition of cell cycle activation. However, the vast majority of patients eventually progress on these therapies, underscoring the need for new treatment strategies to select patients, monitor response, and target novel therapeutic vulnerabilities. We previously reported that high expression of MCM2 and its origin licensing complex (LC) is enriched in primary tumors refractory to CDK4/6i (SABCS22-P2-03-10). LC factors are transcriptionally regulated by E2F/MYC-driven programs, which are activated by diverse drivers of resistance. We propose that MCM2/LC expression may be a biomarker reflecting multiple ET and CDK4/6i resistance mechanisms, due to its role in cell cycle activation.\nMethods: A retrospective review was conducted on a real-world, treatment-naive ER+/HER2- BC cohort of 1,960 largely metastatic patients with biopsies from breast or other sites (~50% each) that underwent NGS profiling (DNA: 592-gene panel/whole-exome; RNA: whole-transcriptome) at Caris Life Sciences. Tumors were stratified by MCM2 or LC gene set mRNA into Q4 (high) versus Q1 (low; n=490 each), balanced for ET/CDK4/6i exposure, MSI-H, and TMB-H. Histology, PAM50, mutations (mut), gene amplifications(amp) and deletions(del), and differential gene expression were analyzed. Chi-square, Fisher’s Exact, or Mann-Whitney U tests were performed with Benjamini-Hochberg FDR for molecular variables (q<0.05).\nResults: MCM2-high vs -low tumors were LumB-dominant (LumB 85.5% vs 39.8%; LumA 5.3% vs 56.3%, p<1e-63) with less lobular histology (6.1% vs 17.1%, p=0.0001). Transcriptomically, PI3K/AKT/mTOR, E2F/MYC targets, G2M checkpoint, and DNA repair hallmark pathways were enriched in MCM2-high (all FDR q<0.05). Genomically, MCM2-high harbored a higher frequency of TP53mut (32.6% vs 16.6%, q=4e-6), RB1mut (5.8% vs 1.2%, q=0.052), CCND1amp (26% vs 6%, q=4.5e-11), FGF3/4/19amp (~25% vs ~6%, q≤2.2e-10), MYCamp (5.4% vs 0.8%, q=0.0136), and CDKN2A/Bdel (CDKN2A 29.3% vs 15.5%, q=6.9e-4; CDKN2B 17.5% vs 7.3%, q=1.38e-3). Notably, MCM2 and MKI67 gene expression were highly correlated (Spearman’s ρ=0.77, p<0.05). Very similar results were found for LC-high vs -low tumors.\nConclusions: In ER+/HER2- BC, high MCM2/LC is associated with LumB subtype, E2F/MYC and cell cycle activation, selection of TP53 and RB1 mutations, and CCND1/MYC/FGF amplifications. Our findings suggest that MCM2 or LC mRNA may act as a surrogate marker for a network of oncogenic pathways previously identified to drive endocrine and CDK4/6i resistance. Future studies will evaluate MCM2/LC beyond proliferation, as a predictive biomarker for CDK4/6i-based regimens, as we have previously shown in the primary ET-treated setting (SABCS24-P1-03-20).", "source_company": "Dan L Duncan Comprehensive Cancer Center", "source_org_type": "医院", "row_number": 628, "target_meta": "CDK4,CDK6", "MOA_meta": "抑制剂"}, {"drug_name": "Siglec-blocking antibodies", "company": "University of Alabama at Birmingham", "org_type": "大学", "target": "Siglec", "modality": "inhibitor", "importance_level": "低", "total_score": 44.5, "institution_score": 20, "track_score": 75, "milestone_score": 40, "field_heat_score": 70, "bonus_score": 3, "brief_reason": "药物为Siglec阻断抗体，靶向Siglec受体阻断PDAC细胞通过唾液酸化配体诱导巨噬细胞M2极化，实现免疫检查点干预；机构为大学学术研究，处于机制探索和体外/动物模型验证阶段，无公司推进，赛道虽属新兴巨噬细胞检查点但整体开发热度和里程碑有限。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10918", "id": "7VXM_5wBX1NQZOEH-LK6", "source_drug_name": "Siglec-blocking antibodies", "title": "Role of sialic acid-siglec axis in pancreatic cancer immune evasion", "abstract_text": "Pancreatic ductal adenocarcinoma (PDAC) is an aggressive malignancy. A key factor contributing to the lethality of PDAC is immune evasion. Tumor cells suppress anti-tumor immunity by activating immune checkpoint proteins on immune cells including macrophages. Siglec receptors are one of the main checkpoint molecules on macrophages. The ligand for Siglecs is sialic acid. To effectuate immune suppression via Siglecs, PDAC cells increase their surface sialylation by upregulating the expression of sialyltransferases such as ST6GAL1. ST6GAL1 adds an α2,6-linked sialic acid to N-glycans. Both α2,6 sialylation and ST6GAL1 expression are markedly increased in PDAC cells. Our prior studies revealed potent tumor-autonomous functions for ST6GAL1. Our new unpublished results suggest that the tumorigenic effects of ST6GAL1 are also driven by its role in creating sialoglycan ligands for macrophage Siglecs. Macrophages that are polarized to an immunosuppressive M2 phenotype are key contributors to PDAC progression. The goal of our study is to determine whether macrophage Siglecs are promising therapeutic targets for preventing M2 polarization, thus restoring anti-tumor immunity and preventing PDAC progression. We investigated macrophage polarization in our genetically engineered mouse models of PDAC, utilizing either pancreas-specific knock-in of oncogenic K-ras (KC mouse) or K-ras in combination with ST6GAL1 knock-in (KSC mouse). Single-cell RNA sequencing, flow cytometry, and immunohistochemistry showed an increased number of M2 macrophages in KSC vs. KC pancreata. Macrophages co-cultured with ST6GAL1-overexpressed PDAC cells showed increased expression of M2 markers. But adding Siglec-blocking antibodies reversed the ST6GAL1-mediated M2 polarization, indicating that the ST6GAL-mediated M2 polarization of macrophages is mediated through Siglec signaling. Additionally, we determined the phagocytotic capacity of macrophages, which is an established functional readout for anti-tumor behavior of macrophages. Immunofluorescence microscopy and flow cytometry showed that the phagocytotic capability of macrophages was suppressed by ST6GAL1-overexpressed PDAC cells but recovered by Siglec blocking antibody. Overall, our data demonstrate that α2,6 sialic acids on PDAC cells engage with Siglecs on macrophages to induce polarization of macrophages into an immunosuppressive M2 phenotype. Collectively, these results reveal a potential mechanism for targeting Siglecs as a promising immune checkpoint therapy for PDAC patients with high levels of ST6GAL1. Traditional T cell-based checkpoint therapies have limited effectiveness in PDAC. Targeting Siglec checkpoints presents an opportunity to enhance the anti-tumor activity of macrophages, the primary immune cell type within the PDAC tumor microenvironment.", "source_company": "University of Alabama at Birmingham", "source_org_type": "大学", "row_number": 641, "target_meta": "Siglec", "MOA_meta": "抑制剂"}, {"drug_name": "GM-0111", "company": "University of Utah", "org_type": "大学", "target": "CCL5", "modality": "other", "importance_level": "低", "total_score": 44.5, "institution_score": 35, "track_score": 45, "milestone_score": 50, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "GM-0111为合成糖胺聚糖，通过强结合并抑制CCL5介导的趋化及内皮细胞CCL5分泌，减轻辐射诱导直肠炎的炎症和氧化应激。大学机构preclinical体外机制研究，赛道非热门肿瘤治疗靶点和modality，综合热度和开发阶段较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3943", "id": "NFXM_5wBX1NQZOEH-LS6", "source_drug_name": "GM-0111", "title": "Mechanistic insights into the radioprotective action of GM-0111 via CCL5 inhibition and endothelial-immune modulation", "abstract_text": "Radiation-induced proctitis (RIP) is a painful inflammatory condition of the rectum affecting up to 20% of cancer patients undergoing pelvic radiation. RIP manifests as a broad spectrum of side effects, which may lead to discontinuation of cancer treatment, and surgical intervention. Current therapeutics are merely symptomatic, highlighting the need for new effective prophylactics. We have demonstrated that synthetic glycosaminoglycan, GM-0111, has promising activity in mitigating the tissue-damaging effects of ionizing radiation when administered prophylactically in a murine model of RIP. We found that immune cell infiltration, and rectal tissue expression of CCL5, a potent chemotactic agent for mast cells and other immune cells, and its associated signaling pathways were significantly reduced with GM-0111 compared to irradiated controls. The mechanisms by which GM-0111 interacts with CCL5 and exerts its prophylactic effects against RIP have yet to be elucidated. We therefore performed a series of in vitro studies using immune and endothelial cells implicated in different stages of RIP. As mast cells hyperplasia and activation have been implicated in RIP development, we hypothesized that GM-0111 inhibits mast cell chemotaxis and degranulation, thereby reducing the immunological response resulting from radiation, including immune cell chemotaxis, activation, and viability and reactive oxygen species (ROS) generation. To test our hypothesis, the effect of GM-0111 treatment on CCL5 secretion and mediated responses was assessed in endothelial cells (HUVECs) and mast cells (P-815 and RBL-2H3). Due to the significant crosstalk between mast cells and macrophages, we also evaluated mast cell degranulation, ROS production, and cell viability using a colorimetric assay, flow cytometry, and quantitative phase imaging. We found that GM-0111 inhibited CCL5-induced chemotaxis with the IC50 of 82 nM. GM-0111 showed strong binding to CCL5 with Kd 3.34 ± 1.21 nM which may play a significant role in inhibiting its chemotactic effect. We also investigated the effect of GM-0111 on CCL5 released from TNF-⍺- and IFN-Ɣ-activated HUVECs, whereby 10 µM GM-0111 caused an 8-fold reduction in CCL5 secretion, suggesting that GM-0111 also interferes with CCL5 production. GM-0111 (10 µM) was found to exert cytoprotective effects on RAW 264.7 cells irradiated with 2.5 Gy and 5 Gy, which may be attributed to decreased ROS production. Collectively, these data demonstrate that GM-0111 exerts coordinated radioprotective effects by attenuating oxidative stress, inhibiting endothelial CCL5 production, and blocking mast cell recruitment. This integrated mechanism positions GM-0111 as a promising prophylactic candidate against radiation-induced injury for supportive cancer care. We would like to acknowledge NIH (5R01CA227225-05) (HG) and NIH (R01CA276653 ) (TAZ) for funding this project.", "source_company": "University of Utah", "source_org_type": "大学", "row_number": 870, "target_meta": "CCL5", "MOA_meta": "其他"}, {"drug_name": "IL-17 blockade", "company": "Fujian Medical University", "org_type": "大学", "target": "IL-17", "modality": "inhibitor", "importance_level": "低", "total_score": 44.5, "institution_score": 25, "track_score": 65, "milestone_score": 55, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "IL-17 blockade针对ICI治疗相关的中枢神经系统irAE中由神经抗原特异性Th17细胞驱动的IL-17依赖性神经毒性。机构为国内大学非产业化主体、仍处于机制研究与个案改善阶段导致整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10449", "id": "e57ECZ0BZznHJdntvNYd", "source_drug_name": "IL-17 blockade", "title": "Persistent neuro-antigen-reactive Th17 cells drive IL-17-dependent neurotoxicity in CNS immune-related adverse events", "abstract_text": "Background: Immune checkpoint inhibitors (ICIs) have transformed cancer outcomes but can induce immune-related adverse events (irAEs) that limit therapy. Central nervous system irAEs (irAE-CNS) are rare, often corticosteroid-refractory, and lead to disabling neurological sequelae. Their immunopathogenesis remains poorly understood, hindering effective interventions. We aimed to define the immune mechanisms underlying irAE-CNS and identify therapeutic targets using multi-omics profiling and longitudinal clinical correlation.\nMethods: We analyzed cerebrospinal fluid (CSF) from three independent irAE-CNS cohorts and controls (autoimmune encephalitis, CNS infection). Multi-omics profiling integrated OLINK proteomics, single-cell secretome and transcriptome analysis, and paired VDJ-TCR repertoire sequencing with FDG-PET/CT imaging, neurofunctional testing, and 15-month follow-up. Unsupervised clustering (Seurat) and clonotype mapping (CellRanger/IGBLAST) were used to define cell phenotypes and track longitudinal persistence. Neuroantigen reactivity was validated via MHC-multimer sorting and peptide libraries derived from neuronal surface proteins, including NMDAR1. Functional assays assessed T-cell-mediated neuronal cytotoxicity and the effects of IL-17 blockade.\nResults: We identified a distinct population of CD4⁺CD137⁺PD-1⁺ effector-memory T-helper cells (Poly6⁺ Th cells) enriched in irAE-CNS, co-secreting IL-17A, TNFRSF9, CCL11, MCP-1, MCP-4, and Granzyme B, defining a polyfunctional Th17-like signature. Poly6⁺ Th-cell frequency correlated with intracranial FDG-PET hypermetabolism especially within limbic regions, and with cognitive decline. Single-cell RNA-seq revealed stable RORC⁺IL23R⁺GZMB⁺ transcriptional profiles, and VDJ analysis showed persistent, antigen-driven clonal expansion. Dominant clonotypes targeted NMDAR1 epitopes (notably EERITGINDPRLRNP), confirming neuroantigen-specific persistence. In co-culture assays, Poly6⁺ Th cells induced neuronal apoptosis via IL-17-dependent mechanisms. In patients treated with IL-17 blockade, neurological symptoms and intracranial inflammation improved significantly without reducing ICI antitumor efficacy.\nConclusions: irAE-CNS is driven by persistent, NMDAR1-reactive Th17-like effector-memory cells that mediate IL-17-dependent neurotoxicity. These findings reveal a mechanistic basis for selective cytokine blockade to alleviate CNS autoimmunity while maintaining checkpoint efficacy, providing a framework for biomarker-guided management of ICI-associated toxicities.", "source_company": "Fujian Medical University", "source_org_type": "大学", "row_number": 963, "target_meta": "IL-17", "MOA_meta": "抑制剂"}, {"drug_name": "mutant estrogen receptor (mER) gene therapy", "company": "Seoul National University", "org_type": "大学", "target": "estrogen receptor", "modality": "gene therapy", "importance_level": "低", "total_score": 44.5, "institution_score": 35, "track_score": 45, "milestone_score": 50, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "该疗法通过过表达DNA结合域突变的非功能性ER（mER）抑制野生型ER并克服内分泌耐药，采用ER靶向PLGA纳米粒递送，在体外和体内模型显示抗肿瘤活性，尤其对tamoxifen耐药模型有效。机构为大学非商业研发、赛道为基因治疗但非热门如CAR/ADC、仅preclinical阶段导致总体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10421", "id": "qZ7M_5wBZznHJdnt_W3O", "source_drug_name": "mutant estrogen receptor (mER) gene therapy", "title": "A novel gene therapy approach for treating breast cancer through the overexpression of mutant estrogen receptor", "abstract_text": "Background: Endocrine therapy (ET) is the primary treatment for hormone receptor-positive (HR+) breast cancer, but resistance inevitably develops, leading to endocrine-resistant breast cancer. While agents like tamoxifen and aromatase inhibitors improve outcomes, resistance mechanisms remain significant challenges. This suggests a complex role for estrogen receptor (ER) signaling. We hypothesized that maintaining a non-functional, mutant ER (mER) could overcome this resistance.\nMethods: We synthesized a full-length ER (ESR1) gene with a mutation in the DNA-binding domain (DBD). To ensure targeted delivery, the mER-encoding plasmid was encapsulated within poly(lactic-co-glycolic acid) (PLGA) nanoparticles. These nanoparticles were surface-functionalized with 4-carboxyl-17beta-estradiol, an ER ligand, to facilitate active targeting to ER-positive breast cancer cells. The effects of mER overexpression were investigated in vitro using HER2-ER+PR+ MCF7 and T47D cell lines, as well as their tamoxifen-resistant (TamR) counterparts. In vivo antitumoral effects were assessed using xenograft mouse models.\nResults: The ER-targeted PLGA nanoparticles effectively delivered the mER plasmid to ER-expressing breast cancer cells in vitro and in vivo. Overexpression of mER did not activate estrogen-responsive genes and exerted a potent antiproliferative effect in both MCF7 and T47D cells. Notably, mER overexpression maintained its strong antitumoral activity in tamoxifen-resistant (TamR) MCF7 and T47D cells. Mechanistically, mER overexpression led to a reduction in wild-type ER (wtER) levels and suppressed DNA replication-related gene pathways. In vivo, mER treatment significantly inhibited the growth of both standard and tamoxifen-resistant tumors. Furthermore, a synergistic antitumoral effect was observed when mER was combined with tamoxifen.\nConclusions: Overexpression of a mutant ER with a non-functional DBD, delivered via an ER-targeted nanoparticle system, represents a novel therapeutic strategy for advanced HR+ breast cancer, including endocrine-resistant and tamoxifen-resistant disease. By suppressing wtER, disrupting DNA replication, and maintaining activity in resistant models, mER effectively inhibits tumor growth and overcomes therapeutic resistance.", "source_company": "Seoul National University", "source_org_type": "大学", "row_number": 1068, "target_meta": "ER", "MOA_meta": "基因疗法"}, {"drug_name": "hit compounds", "company": "Sasaki Foundation", "org_type": "研究机构", "target": "未披露", "modality": "inhibitor", "importance_level": "低", "total_score": 44.5, "institution_score": 25, "track_score": 65, "milestone_score": 45, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "hit compounds为小分子抑制剂，靶向阻断DGC细胞与CAF异细胞黏附，但具体靶点未披露。研究机构背景+早期hit阶段+新型肿瘤微环境靶向策略导致整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10811", "id": "t57M_5wBZznHJdnt_W3O", "source_drug_name": "hit compounds", "title": "Identification and characterization of compounds that block heterocellular adhesion between diffuse-type gastric cancer cells and cancer-associated fibroblasts", "abstract_text": "The phenotypes of cancer cells are profoundly influenced by reciprocal interaction with the tumor stroma within the tumor microenvironment. Among stromal components, cancer-associated fibroblasts (CAFs) are the most abundant and play pivotal roles in shaping the tumor milieu. CAFs promote cancer progression through the secretion of pro-tumorigenic factors and remodeling of the extracellular matrix. In addition to these paracrine effects, recent studies have emphasized the critical role of direct heterocellular adhesion between cancer cells and CAFs in tumor progression. Diffuse-type gastric cancer (DGC) is the most aggressive subtype of gastric cancer with an extremely poor prognosis. DGC is characterized by rapid infiltrative growth and frequent peritoneal metastasis. DGC is commonly accompanied by desmoplastic stroma, which results from the extensive proliferation of CAFs. We previously demonstrated that direct interactions with CAFs are essential for the invasion and peritoneal metastasis of DGC cells. To further elucidate the biological significance of this interaction, we established a high-throughput screening system to identify molecules that disrupt DGC cell-CAF adhesion. Using this screening system, we successfully obtained monoclonal antibodies that block this heterocellular adhesion and suppress peritoneal metastasis of DGC in vivo. In the present study, we aimed to identify small-molecule compounds that inhibit heterocellular adhesion between DGC cells and CAFs. High-throughput screening of a chemical library led to the identification of several hit compounds. Notably, one compound not only inhibited DGC cell-CAF adhesion but also suppressed the proliferation of DGC cells. Furthermore, this compound markedly reduced peritoneal metastasis of DGC in a mouse xenograft model. These findings suggest that targeting the heterocellular adhesion between cancer cells and CAFs represents a promising therapeutic strategy, and that small molecules disrupting this interaction may serve as novel anti-cancer agents.", "source_company": "Sasaki Foundation", "source_org_type": "研究机构", "row_number": 1081, "target_meta": "not available", "MOA_meta": "抑制剂"}, {"drug_name": "ES936", "company": "University Hospital Wuerzburg", "org_type": "医院", "target": "NQO1", "modality": "inhibitor", "importance_level": "低", "total_score": 44, "institution_score": 30, "track_score": 60, "milestone_score": 50, "field_heat_score": 60, "bonus_score": 2, "brief_reason": "ES936为NQO1机制性抑制剂，在多发性骨髓瘤模型中逆转蛋白酶体抑制剂及抗CD38抗体耐药，机制新颖。机构为医院学术型，preclinical工具化合物阶段，无产业化推进，打分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3762", "id": "fVXM_5wBX1NQZOEH-LK6", "source_drug_name": "ES936", "title": "NQO1 as a target to overcome therapy resistance in multiple myeloma", "abstract_text": "Background: Overexpression of NAD(P)H:quinone oxidoreductase 1 (NQO1) has been linked to poor prognosis and therapy resistance in solid tumors, but its role in multiple myeloma (MM) remains unclear. Combination therapies including proteasome inhibitors (PIs), immunomodulatory drugs (IMiDs), and/or immunotherapies have improved outcomes in MM, yet most patients eventually develop resistant and relapse. We recently identified NQO1 overexpression across PI-resistant MM models and that high NQO1 expression is associated with inferior outcome in PI treated MM patients. Hence, we here extend these findings in an independent MM cohort (n = 93) from our institution and in NQO1 upregulated MM cell line models to examine how NQO1 affects MM immunotherapy targets and sensitivity to standard treatment regimens.\nMethods: RNA-seq was performed on bone marrow-derived CD138+ cells from 24 newly diagnosed MM (NDMM) and 69 relapsed/refractory MM (RRMM) patients, as well as MM cell lines. Surface density of immunotherapy targets was quantified via direct stochastic Optical Reconstruction Microscopy (dSTORM). Sensitivity to PIs and IMiDs was assessed using AlamarBlue assays.\nResults: In the MM RNA-seq cohort, NQO1 expression was significantly higher in RRMM compared with NDMM (p = 0.0002), supporting an association of NQO1 with treatment-exposed, advanced disease. Furthermore, overexpression of NQO1 in MM cell lines led to an increased IC50 for bortezomib and carfilzomib, whereas IMiDs sensitivity remained intact. No upregulation of PI resistance-related genes was identified by RNA-seq. To test whether NQO1-dependent mechanisms are causative for PI resistance, NQO1-high MM cells were treated with NQO1 inhibitor ES936, which restored the sensitivity to both PIs to the wild type levels. In subsequent dSTORM analysis, no differences were observed in BCMA, SLAMF7, or GPRC5D, whereas CD38 surface density was significantly reduced in both NQO1-High myeloma cell lines. Consistent with the expression data, NQO1-overexpressing cells showed reduced sensitivity to CD38-directed therapies (daratumumab (Dara) and isatuximab (Isa). Notably, NQO1 inhibition with ES936 restored CD38 surface expression and rescued Dara and Isa responses, supporting that NQO1 is directly involved in CD38 downregulation and resistance to anti-CD38 antibodies. Of note, RNA-seq comparison of NQO1-high vs. WT MM models did not reveal changes in CD38 mRNA levels, pointing toward a post-translational mechanism, such as altered protein stability or trafficking.\nConclusions: NQO1 is upregulated in RRMM and functionally induces resistance to PIs and CD38-directed therapies which are widely used in current MM treatment. Inhibition of NQO1 with ES936 rescues CD38 expression, and restores PI sensitivity and anti-CD38 responses, supporting NQO1 as a promising target in treatment-exposed or relapsed MM.", "source_company": "University Hospital Wuerzburg", "source_org_type": "医院", "row_number": 566, "target_meta": "NQO1", "MOA_meta": "抑制剂"}, {"drug_name": "Oncuria-Detect", "company": "Cedars-Sinai Medical Center", "org_type": "医院", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 44, "institution_score": 30, "track_score": 60, "milestone_score": 50, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "Oncuria-Detect为尿液多重免疫分析检测膀胱癌相关蛋白生物标志物签名，靶点未明确单一药物靶向而是诊断性多标志物panel。机构为医院非药企、赛道为体外诊断工具非热门治疗modality、处于国际前瞻性研究中期分析阶段，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10203", "id": "g1XM_5wBX1NQZOEH-LS6", "source_drug_name": "Oncuria-Detect", "title": "Detection of bladder cancer in patients with microscopic hematuria using Oncuria-Detect, interim analysis of an international prospective study", "abstract_text": "Background - Microscopic hematuria occurs in up to 10% of the general population and initiates costly evaluation to ensure no bladder cancer exists. Oncuria-Detect is a 10-plex immunoassay that detects de novo bladder cancer by generating a protein biomarker signature from a single voided urine sample. This report details the interim analysis of our prospective study that compares the diagnostic performance of the multiplex Oncuria-Detect assay to that of the single-analyte (i.e., NMP22) BladderChek urine assay and urine cytology for identifying bladder cancer in patients with microscopic hematuria.\nMethods - From September 2018 through July 2025, 9 medical facilities in the US and Japan prospectively enrolled 292 eligible patients (~30%) of the proposed 900 patients with microscopic hematuria into this study. The bladder cancer diagnostic reference standard was cystoscopy with biopsy. Pre-cystoscopy, patients provided a urine sample for analysis by Oncuria-Detect and BladderChek (analyzed in a blinded manner) as well as urine cytology.\nResults - Bladder cancer was diagnosed in 22 patients (7.5%). The Oncuria-Detect assay had the following performance characteristics 82.0% sensitivity, 37.8% specificity, 97.5% adjusted negative predictive value (NPV) compared to BladderChek (9.3% sensitivity, 99.6% specificity, 95.4% adjusted NPV) and cytology (44.8% sensitivity, 99.3% specificity, 97.2% adjusted NPV). Oncuria-Detect displayed better sensitivity than BladderChek and cytology for identifying early- and late-stage cancer.\nConclusions - In this interim analysis of an international prospective trial, Oncuria-Detect performed favorably in the non-invasive evaluation of bladder cancer presence in patients presenting with microscopic hematuria.", "source_company": "Cedars-Sinai Medical Center", "source_org_type": "医院", "row_number": 924, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "anti-PD-1", "company": "University of Miami", "org_type": "大学", "target": "PD-1", "modality": "inhibitor", "importance_level": "低", "total_score": 43.5, "institution_score": 25, "track_score": 75, "milestone_score": 35, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "药品为anti-PD-1抗体（PD-1抑制剂），摘要聚焦于dovitinib（多靶点RTK抑制剂）联合anti-PD-1在胃癌模型中的协同增强免疫治疗效果，但未披露任何新型anti-PD-1药物信息。大学机构、非临床阶段协同机制研究导致总体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8926", "id": "1FXM_5wBX1NQZOEH-LG6", "source_drug_name": "anti-PD-1", "title": "Targeting multivalent receptor tyrosine kinases to enhance the efficacy of anti-PD-1 immunotherapy in gastric cancer", "abstract_text": "Background: Gastric cancer (GC) is the fifth most common cancer and the fifth leading cause of cancer-related deaths globally. The response to immune checkpoint blockade (ICB) therapy in GC is relatively poor with almost two thirds of the patients not responding due to the tumor's ability to maintain an immunosuppressive microenvironment and develop resistance to immunotherapy. Previously, we demonstrated that dovitinib, a multi-target receptor tyrosine kinases (RTKs) inhibitor, suppresses tumor growth and remodels the tumor microenvironment (TME) by facilitating the recruitment of CD8+ T cells into immune-suppressive types of mouse gastric cancer. This study aimed to assess whether dovitinib enhances the therapeutic effectiveness of PD-1 blockade.\nMethods: ATP-GLO to measure cell viability in vitro. A syngeneic murine gastric tumor model with two distinct mouse GC cell lines was utilized to assess the synergistic effects of dovitinib and anti-PD-1 treatment. IF and flow cytometry to immunophenotyping.\nResults: The combination of dovitinib and PD-1 blockade was significantly more effective than either treatment alone, leading to reduced tumor growth and increased animal survival in both models (p<0.01). IF analysis revealed that while dovitinib alone increased CD8+ T cell infiltration in the tumor core, the combination treatment further enhanced the infiltration of cytotoxic T cells (Perforin+ CD8+) compared to the other groups (p<0.01). Furthermore, multiparametric flow cytometry combined with FlowSOM clustering analysis showed an increase in CD4+ and CD8+ T cell clusters with higher activation (CD69+) and lower or absent expression of exhaustion markers (PD-1, CTLA-4). In contrast, dovitinib alone was associated with a more exhausted T cell phenotype. Notably, only the combination treatment increased the tumor killing capacity of the cytotoxic T cells.\nConclusion: Our findings demonstrate that the combination of dovitinib and PD-1 blockade is significantly more effective than either treatment alone, as the two therapies synergistically remodel the TME beyond their direct cytotoxic effects. This synergy is achieved by increasing the infiltration of activated tumor-infiltrating lymphocytes (TILs) and reducing the exhaustion phenotype typically seen with monotherapy. This study supports the rationale for combining multi-target RTKs inhibitors with immunotherapies as an effective therapeutic strategy for gastric cancer.", "source_company": "University of Miami", "source_org_type": "大学", "row_number": 19, "target_meta": "PD1", "MOA_meta": "抑制剂"}, {"drug_name": "terfenadine derivatives", "company": "University at Buffalo SUNY", "org_type": "大学", "target": "TFE3-O dimerization", "modality": "inhibitor", "importance_level": "低", "total_score": 43.5, "institution_score": 25, "track_score": 65, "milestone_score": 45, "field_heat_score": 55, "bonus_score": 2, "brief_reason": "基于terfenadine改造的小分子抑制剂，靶向TFE3融合蛋白二聚化，针对罕见tRCC亚型，目前处于工具化合物优化阶段，改善抗增殖活性和降低心脏毒性。大学早期研究，靶点新颖但非热门赛道、开发阶段早、临床转化前景有限。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5714", "id": "NVXM_5wBX1NQZOEH-LS6", "source_drug_name": "terfenadine derivatives", "title": "Development of terfenadine-derived small-molecule inhibitors of TFE3-O dimerization for translocation renal cell carcinoma", "abstract_text": "Translocation renal cell carcinoma (tRCC) is an aggressive kidney cancer subtype with poor clinical outcome and no effective standard therapies. It is characterized by gene fusions involving members of the MiT transcription factor family, most commonly TFE3 fused to various partner genes. Work from our laboratory has previously identified the antihistamine terfenadine as a promising compound capable of inhibiting TFE3 dimerization, highlighting dimerization as a targetable mechanism in tRCC. These findings suggest that disrupting TFE3 fusion protein dimerization may enhance therapeutic response and could be leveraged in combination with existing treatment options, including tyrosine kinase inhibitors (TKIs).\nThe purpose of this study was to optimize terfenadine-derived tool compounds and identify novel small molecules that enhance its antiproliferative activity while reducing terfenadine well-known long QT associated cardiotoxicity. We aimed to determine whether these derivatives selectively inhibit dimerization of TFE3 fusion proteins and improve activity against tRCC diminishing hERG interaction and cardiotoxicity. Two series of terfenadine analogs based on chemical structure modifications were synthesized to evaluate groups specific functional contribution. All compounds were purified and structurally verified by NMR, LTQ mass spectrometry, and HPLC. Their antiproliferative activity was assessed in tRCC cell lines harboring distinct TFE3 fusions (R07: SPFQ-TFE3; UOK-109: NONO-TFE3; UOK-146: PRCC-TFE3). FRET-based assays are being established to measure inhibition of TFE3/TFE3-O dimerization, and hERG activity monitored.\nSeveral newly synthesized compounds, in particular two leading candidates exhibited improved antiproliferative effects (IC50s ~2 µM) as compared to terfenadine (IC50s ~7 µM). These results provide a foundation for further structural refinement and assessment of pharmacological properties with modifications also aiming to reduce its cardiotoxic effect. Combination studies with TKIs demonstrated that co-treatment with terfenadine significantly reduced IC50 values relative to monotherapy, as confirmed by Combination Index analysis. This supports the hypothesis that inhibiting TFE3 fusion protein dimerization enhances drug response to TKIs, potentially by reducing drug sequestration in the lysosome.\nIn conclusion, this work identifies terfenadine derivatives with improved antiproliferative potential and reduced predicted cardiotoxicity, and highlights TFE3 dimerization as a therapeutically targetable mechanism that may help overcome drug resistance in tRCC.", "source_company": "University at Buffalo SUNY\nUniversity at Buffalo", "source_org_type": "大学", "row_number": 73, "target_meta": "TFE3", "MOA_meta": "抑制剂"}, {"drug_name": "chloroquine/hydroxychloroquine", "company": "University of North Carolina at Chapel Hill", "org_type": "大学", "target": "autophagy pathway", "modality": "inhibitor", "importance_level": "低", "total_score": 43.5, "institution_score": 35, "track_score": 45, "milestone_score": 50, "field_heat_score": 55, "bonus_score": 0, "brief_reason": "药物为自噬抑制剂CQ/HCQ，靶向自噬通路，但临床疗效有限。大学机构基础研究，垂直抑制策略属preclinical层面，赛道非当前最热门，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4667", "id": "nJ7M_5wBZznHJdnt_W3O", "source_drug_name": "chloroquine/hydroxychloroquine", "title": "Vertical inhibition of the autophagy pathway promotes growth arrest and apoptotic cell death in pancreatic ductal adenocarcinoma", "abstract_text": "Pancreatic ductal adenocarcinoma (PDAC) is dependent on autophagy for growth. The sole FDA approved inhibitor of autophagy, chloroquine/hydroxychloroquine (CQ/HCQ), inhibited the growth of multiple preclinical models of PDAC. However, clinical trials using CQ alone or in combination with standards of care have shown that CQ has limited clinical efficacy. To identify genes to target as sensitizers to CQ treatment, we performed a CQ-anchored CRISPR-Cas9 mediated loss-of-function screen. We identified multiple autophagy-related genes. This result led us to hypothesize that concurrent inhibition of two nodes (i.e. vertical inhibition) of the autophagy pathway is a more effective method of inhibiting cell growth. Specifically, loss of PIK3C3, the gene that encodes VPS34, a protein essential for autophagosome nucleation, sensitized PDAC cells to CQ treatment. We validated this finding via both genetic depletion and pharmacological inhibition with the compound SAR405. Additionally, pharmacological inhibition of ULK1/2, the serine/threonine kinases critical for autophagy initiation, further reduced CQ-mediated anti-proliferative effects. We recently demonstrated that inhibition of the lipid kinase PIKfyve with apilimod potently suppressed autophagy in PDAC. We found that both ULK1/2 and VPS34 inhibitor treatment sensitized cells to PIKfyve inhibition.To elucidate the mechanisms driving decreased cellular proliferation following combination treatment, we explored both autophagy-dependent and -independent pathways using reverse phase protein array (RPPA) based protein pathway activation mapping. We determined that vertical autophagy inhibition resulted in metabolic rewiring including enhanced receptor tyrosine kinase and PI3K-AKT-mTORC1 signaling. Furthermore, by monitoring levels of the autophagy-related protein LC3B following CQ or apilimod treatment alone or in combination with ULK1/2 inhibition, we demonstrated that vertical autophagy inhibition impairs both autophagosome formation and autophagosome processing, simultaneously. We also found that cleaved caspases accumulated more in the presence of two autophagy inhibitors. We validated this finding using Annexin V apoptosis assays and demonstrated that growth suppression was due in part to enhanced apoptotic cell death. In summary, our findings demonstrate that vertical inhibition of the autophagy pathway more effectively suppresses autophagy and increases cell death in PDAC and provides rationale for a vertical inhibition strategy to enhance the therapeutic efficacy of autophagy inhibition.", "source_company": "University of North Carolina at Chapel Hill", "source_org_type": "大学", "row_number": 87, "target_meta": "not available", "MOA_meta": "抑制剂"}, {"drug_name": "Bruton's tyrosine kinase inhibitor", "company": "Ohio State University College of Medicine", "org_type": "大学", "target": "BTK", "modality": "inhibitor", "importance_level": "低", "total_score": 43.5, "institution_score": 35, "track_score": 75, "milestone_score": 20, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "药品为BTK抑制剂，靶点明确但摘要无任何具体药物或研究数据，仅为泛指类别。大学机构非主要研发主体、缺乏开发阶段信息导致总体分值偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/616", "id": "9FXM_5wBX1NQZOEH-LC5", "source_drug_name": "Bruton's tyrosine kinase inhibitor", "title": "Bruton’s tyrosine kinase inhibitor resistance in chronic lymphocytic leukemia: Implications for therapeutic sequencing", "abstract_text": "There is no abstract associated with this presentation.", "source_company": "Ohio State University College of Medicine", "source_org_type": "大学", "row_number": 299, "target_meta": "BTK", "MOA_meta": "抑制剂"}, {"drug_name": "PD-L1-targeted extracellular vesicles carrying HSV-TK mRNA", "company": "Kyungpook National Univ.", "org_type": "大学", "target": "PD-L1", "modality": "other", "importance_level": "低", "total_score": 43.5, "institution_score": 25, "track_score": 65, "milestone_score": 45, "field_heat_score": 55, "bonus_score": 2, "brief_reason": "该药物利用PD-L1靶向的细胞外囊泡递送HSV-TK mRNA实现肿瘤选择性自杀基因治疗，机制新颖但仍处于早期探索阶段。大学机构、非热门modality、仅体外+小鼠异种移植瘤水平导致整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6399", "id": "XFXM_5wBX1NQZOEH-LG5", "source_drug_name": "PD-L1-targeted extracellular vesicles carrying HSV-TK mRNA", "title": "Targeted delivery of suicide gene to tumor cells using PD-L1-targeted extracellular vesicles for cancer therapy", "abstract_text": "Herpes simplex virus-thymidine kinase (HSV-TK) gene, a well-known suicide gene, causes cell death in rapidly dividing cells when treated with ganciclovir (GCV). The HSV-TK activates GCV and makes GCV-triphosphate. Insertion of activated GCV-triphosphate in elongating DNA by cellular DNA polymerases interferes DNA duplication and eventually leads to cell death. The suicide gene therapy, however, has been limited by non-specific cytotoxicity in off-target cells such as normal cells. In this study, we explored PD-L1-targeted extracellular vesicles (EVs) carrying the HSV-TK mRNA to deliver the HSV-TK selectively into tumor cells. HEK 293FT cells were transduced using lentivirus with the GFP-tagged, HSV-TK gene containing a sequence that is recognized by EV-trafficking RNA-binding protein. Stable HEK 293FT cells expressing the HSV-TK gene were established. EVs were isolated from the stable cells and labeled with a PD-L1-binding peptide (CVRARTR) using click chemistry to target PD-L1-high tumor cells. Delivery of the HSV-TK mRNA after incubation of cells with the EVs was validated by observing the fluorescence of GFP tag under a microscope. The PD-L1-targeted EVs carrying the HSV-TK mRNA exerted an efficient cytotoxicity in PD-L1-high MDA-MB-231 tumor cells. On the other hand, the EVs showed low levels of cytotoxicity in PD-L1-low tumor cells and normal cells. Systemic administration of the EVs inhibited the growth of MDA-MB-231 tumor xenografts in mice. These results demonstrate that the PD-L1-targeted EVs containing the HSV-TK mRNA provide a new avenue for the targeted delivery of a suicide gene. Keywords: HSV-TK; Peptide; PD-L1; Suicide gene therapy", "source_company": "Kyungpook National Univ.", "source_org_type": "大学", "row_number": 376, "target_meta": "PDL1", "MOA_meta": "其他"}, {"drug_name": "CLDN targeted ADCs", "company": "Massachusetts General Hospital", "org_type": "医院", "target": "CLDN", "modality": "ADC", "importance_level": "低", "total_score": 43.5, "institution_score": 30, "track_score": 85, "milestone_score": 20, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "针对CLDN家族的ADC，属于热门ADC赛道和CLDN（如CLDN18.2）靶点，但靶点表述宽泛未具体到亚型，且摘要无任何内容披露具体药物或开发进展。由医院机构呈现，仅为翻译性 rationale 讨论，无实质研发里程碑。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/423", "id": "O57ECZ0BZznHJdntvNYd", "source_drug_name": "CLDN targeted ADCs", "title": "Beyond monoclonal antibodies: Translational rationale for CLDN targeted ADCs and bispecific therapies", "abstract_text": "There is no abstract associated with this presentation.", "source_company": "Massachusetts General Hospital", "source_org_type": "医院", "row_number": 423, "target_meta": "CLDN", "MOA_meta": "抗体偶联药物"}, {"drug_name": "PARP inhibitor", "company": "Sheba Medical Center", "org_type": "医院", "target": "未披露", "modality": "inhibitor", "importance_level": "低", "total_score": 43.5, "institution_score": 25, "track_score": 75, "milestone_score": 30, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "PARP抑制剂为胰腺癌中germline BRCA突变患者的已建立治疗，但本研究未披露具体药物，仅为液体活检5hmC生物标志物探索其应答差异。机构为医院而非药企、仅为pilot生物标志物研究而非药物开发导致总体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9784", "id": "Pp7ECZ0BZznHJdntvNYd", "source_drug_name": "PARP inhibitor", "title": "Epigenomic liquid biopsy-based biomarkers of platinum and PARP inhibitor response in patients with germ line BRCA-associated PDAC: A pilot study", "abstract_text": "Background: Despite favorable overall response, pancreatic ductal adenocarcinoma (PDAC) patients with germline BRCA mutations show varied response to platinum-based chemotherapy and PARP inhibitor treatment. While some patients demonstrate long term response, others develop acquired resistance after an initial durable response and a third group are refractory to first-line platinum-based therapy. 5-hydroxymethylation (5hmC) analysis of plasma-derived cell-free DNA (cfDNA) of PDAC patients present a non-invasive approach to investigate treatment response biomarkers. Here, we investigated 5hmC profiles of plasma-derived cfDNA obtained from PDAC patients prior to treatment and while on treatment. Additionally, samples were evaluated for response by CA19-9 measurements and the Avantect Pancreatic Cancer Test (Avantect, a non-invasive, blood-based assay designed to detect PDAC using epigenomics and genomics biomarkers.\nMethods: A total of 80 blood samples were collected in EDTA tubes from 32 PDAC patients pre-treatment or while on-treatment, with 2-5 timepoints for each patient. Blood samples were processed to obtain plasma. Cell-free DNA extracted from plasma were analyzed using Avantect. Germline BRCA1/2 mutations were confirmed for all study subjects.\nResults: Of the 32 patients included in the study, 6 were refractory, 14 developed acquired resistance and 12 were long term responders to platinum/PARP-inhibitor treatment. Differential 5hmC analysis at the earliest available timepoint for each patient revealed refractory patients to have distinct cfDNA profiles relative to both acquired resistance and long-term responders. Analysis with Avantect showed that the refractory group exhibited the highest cancer scores when compared to the acquired resistance and long-term responder groups (p value 0.001). Stratification of stage IV patients according to Avantect test results revealed that cancer signal-detected patients have poor overall survival relative to cancer signal not-detected patients (9.3 months vs 25.9 months, Hazard ratio 4.17, p = 0.017). Furthermore, evaluation of on-treatment timepoints demonstrated that Avantect detected disease progression in 78.6% (11/14) of PDAC patients who developed acquired resistance.\nConclusions: cfDNA 5hmC analysis revealed clear differences between long-term responders and patients with resistance, highlighting potential blood-based biomarkers of treatment durability and mechanisms of resistance.​ Cancers with worse response to therapy were detected at a higher rate by the Avantect test. These findings suggest that larger studies using Avantect can be performed to identify patient subpopulations with limited treatment response and to monitor treatment response.", "source_company": "Sheba Medical Center", "source_org_type": "医院", "row_number": 434, "target_meta": "not available", "MOA_meta": "抑制剂"}, {"drug_name": "CAR T cells", "company": "Stanford Hospital", "org_type": "医院", "target": "未披露", "modality": "CAR", "importance_level": "低", "total_score": 43.5, "institution_score": 35, "track_score": 85, "milestone_score": 20, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "药品为CAR-T细胞疗法，靶点未在摘要中披露（无摘要内容），赛道为热门的细胞治疗尤其是儿科脑瘤应用。机构为医院/学术型，开发阶段信息缺失导致里程碑分低，总分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/771", "id": "tlXM_5wBX1NQZOEH-LG6", "source_drug_name": "CAR T cells", "title": "CAR T cells for pediatric brain tumors", "abstract_text": "There is no abstract associated with this presentation.", "source_company": "Stanford Hospital", "source_org_type": "医院", "row_number": 441, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "scFv47", "company": "Levine Cancer Institute", "org_type": "医院", "target": "IL13Rα2", "modality": "CAR", "importance_level": "低", "total_score": 43.5, "institution_score": 25, "track_score": 75, "milestone_score": 35, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "scFv47靶向IL13Rα2，用于胶质母细胞瘤的CAR-T开发；机构为医院非商业化研发，开发阶段为计算方法学优化而非药物实体进展，赛道虽热门但整体里程碑价值有限。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3271", "id": "PFXM_5wBX1NQZOEH-LK6", "source_drug_name": "scFv47", "title": "Mechanism-driven post-AI refinement enables accurate structure prediction of therapeutic antibody-antigen complexes for rational CAR-T and antibody design", "abstract_text": "Accurate prediction of antibody-antigen complexes remains a major challenge for AI-based structural modeling, with current methods failing to model over 50% of interactions. We developed a post-AI refinement strategy to correct AlphaFold predictions when they conflict with experimental observations, specifically for therapeutic antibodies exhibiting competitive binding mechanisms. We applied AlphaFold3 and AlphaRED to predict the structure of scFv47- IL13Rα2 complex, a therapeutic target for glioblastoma. When initial predictions failed to recapitulate experimentally validated competitive binding between scFv47 and IL13, we developed a computational post-AI refinement workflow incorporating mechanism-driven constraints. Using Rosetta-based replica exchange docking, we performed 42 independent trials (>2,500 CPU-hours) with stepwise global-to-local docking refinement. Signal-to-noise filtering identified energetically favorable structures with minimal variance. The refined hypothetical 3D model successfully aligned with experimental observations. In silico mutagenesis recapitulated published data showing Y207, D271, Y315, and D318 residues are critical for IL13 binding but dispensable for scFv47 interaction. Computed interface scores correlated with experimentally-measured binding affinities (IL13-IL13Rα2±2: KD=500pM vs. scFv47-IL13Rα2±2: KD=1.39nM). Structural analysis revealed scFv47 heavy chain CDRs engage the D2 domain while light chain CDR1 primarily contacts D1, providing a rational template for affinity optimization. Validation using cetuximab-EGFR system (with available crystal structure PDB:1YY9) demonstrated >80% epitope overlap, confirming algorithm generalizability across competitive binding systems. This mechanism-driven post-AI refinement framework successfully corrects AlphaFold prediction failures for antibody-antigen complexes, enabling structure-guided therapeutic development when experimental structures are unavailable. The methodology is applicable to CAR-T targeting domains and FDA-approved antibodies, accelerating rational antibody engineering.", "source_company": "Levine Cancer Institute", "source_org_type": "医院", "row_number": 523, "target_meta": "IL-13Rα2", "MOA_meta": "其他"}, {"drug_name": "novel small molecules", "company": "University Hospital Hradec Kralove", "org_type": "医院", "target": "未披露", "modality": "inhibitor", "importance_level": "低", "total_score": 43.5, "institution_score": 25, "track_score": 65, "milestone_score": 45, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "药品为新型小分子化疗增敏剂，靶点和确切机制未披露，非经典DDR途径调控。医院机构研发，前临床阶段筛选出若干候选物且具BBB渗透性，但整体开发阶段早期且非热门靶点驱动，综合重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6557", "id": "UFXM_5wBX1NQZOEH-LK6", "source_drug_name": "novel small molecules", "title": "From phenotypic screening to mechanistic insight: Rational discovery of chemosensitizers for glioblastoma", "abstract_text": "Glioblastoma multiforme (GBM) represents the most aggressive form of primary brain tumor, characterized by rapid progression, therapeutic resistance, and near-universal recurrence. Despite multimodal treatment strategies—comprising maximal surgical resection followed by radiotherapy and temozolomide (TMZ)-based chemotherapy—median survival remains dismal, with most patients succumbing within one-year post-diagnosis. TMZ and ionizing radiation exert their cytotoxic effects primarily through the induction of DNA lesions, including single- and double-strand breaks. The cellular DNA damage response (DDR), encompassing a complex signaling network of kinases, repair enzymes, and checkpoint regulators, orchestrates the detection and repair of these lesions. Dysregulation or hyperactivation of DDR pathways—including those mediated by ATR/ATM signaling, PARP-dependent repair, and cell cycle checkpoints (e.g., WEE1, CDK1)—has been implicated in the pronounced therapeutic resistance of GBM. In this study, we pursued the rational design and synthesis of novel small molecules aimed at potentiating TMZ- and radiation-induced cytotoxicity in GBM. Over seventy compounds were generated across five focused series using structure-based design principles. Phenotypic screening was conducted in the TMZ-resistant T98G line and patient-derived GBM cultures to evaluate both intrinsic cytotoxicity and TMZ sensitization. Several lead candidates demonstrated superior chemosensitization efficacy compared to clinical DDR inhibitors. Interestingly, broad kinase profiling revealed an absence of canonical DDR kinase inhibition, indicating a potential non-classical mechanism of action. To delineate this mechanism, comprehensive quantitative proteomic analyses were performed, revealing modulation of pathways associated with DNA repair, stress response, and cell cycle control. The most promising candidates exhibited favorable pharmacokinetic and toxicological properties, along with effective blood-brain barrier penetration in vivo.\nThis work has been supported by the grant from the Ministry of Health of the Czech Republic (NW24J-03-00005); and by the Long-term development plan Military Faculty of Medicine, Healthcare Challenges of WMD II (DZRO-VLF22-ZHN II).", "source_company": "University Hospital Hradec Kralove", "source_org_type": "医院", "row_number": 538, "target_meta": "not available", "MOA_meta": "抑制剂"}, {"drug_name": "elesclomol-copper", "company": "University of Toledo", "org_type": "大学", "target": "HSF1", "modality": "other", "importance_level": "低", "total_score": 43.5, "institution_score": 30, "track_score": 65, "milestone_score": 40, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "药品为elesclomol-copper铜离子载体，通过诱导铜应激靶向HSF1破坏PDAC细胞线粒体Fe-S蛋白稳定性并增强铜介导的细胞毒性。机构为大学非商业研发、处于基础机制研究阶段无明确临床推进、铜死亡相关赛道有一定热度但整体学术性强导致总分较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6081", "id": "YlXM_5wBX1NQZOEH-LK6", "source_drug_name": "elesclomol-copper", "title": "Targeting heat shock factor 1 in pancreatic ductal adenocarcinoma autophagy and iron-sulfur cluster protein stability", "abstract_text": "Background: Pancreatic ductal adenocarcinoma (PDAC) cells exhibit elevated copper levels, an essential cofactor for cellular function, to support pancreatic tumor growth. Recent studies show that high levels of copper disrupt mitochondrial function by downregulating iron-sulfur (Fe-S) cluster proteins, leading to proteotoxic stress response and cell death; however, the detailed mechanism remains unclear. Heat shock factor 1 (HSF1), a key regulator of the proteotoxic stress response, is highly expressed in PDAC and supports protein stability, mitochondrial function, and tumor progression. This suggests HSF1 may help PDAC cells resist copper-induced cytotoxicity. The copper treatment also induces autophagy, yet whether copper-induced autophagy is regulated by HSF1 is not fully understood.\nObjective: The objective of this study is to study the role of HSF1 in copper-mediated loss of mitochondrial Fe-S cluster proteins and autophagy in PDAC cells.\nMethods and Results: In PDAC cell lines MIA PaCa-2 and PANC-1, treatment with copper ionophore elesclomol-copper (ES-Cu) led to reduced protein levels of mitochondrial Fe-S cluster proteins, including aconitase 2 (ACO2), ferredoxin 1 (FDX1), and lipoic acid synthase (LIAS), but not mRNA expression. Notably, HSF1 overexpression rescued the ES-Cu-decreased protein levels of ACO2, FDX1, and LIAS. Pharmacological inhibition of HSF1 led to increased lipidation of the autophagy marker microtubule-associated protein 1A/1B-light chain 3 (LC3). To investigate the mechanism of ES-Cu-mediated decrease of Fe-S cluster proteins, we pre-treated MIA PaCa-2 cells with hydroxychloroquine (CQ) along with ES-Cu. CQ did not rescue the ES-Cu-mediated decrease in Fe-S cluster proteins, suggesting that the degradation of Fe-S cluster proteins is not mediated by autophagy in copper-mediated cytotoxicity. Interestingly, inhibition of the mitochondrial-specific protease reversed the decrease in Fe-S cluster proteins under ES-Cu stress. Further, HSF1 inhibition with a small-molecule inhibitor significantly enhanced ES-Cu-reduced cell viability in PDAC cells.\nConclusion: Our findings suggest that HSF1 protects PDAC cells from mitochondrial toxicity by maintaining the stability of Fe-S proteins under copper stress. Targeting HSF1 in combination with copper-based therapies may enhance treatment efficacy by disrupting mitochondrial stress adaptation in PDAC.", "source_company": "University of Toledo", "source_org_type": "大学", "row_number": 548, "target_meta": "HSF1", "MOA_meta": "其他"}, {"drug_name": "Scd1 inhibitor", "company": "UCI School of Medicine", "org_type": "大学", "target": "Scd1", "modality": "inhibitor", "importance_level": "低", "total_score": 43.5, "institution_score": 30, "track_score": 45, "milestone_score": 55, "field_heat_score": 50, "bonus_score": 0, "brief_reason": "Scd1抑制剂针对癌相关脂肪细胞中Scd1过表达，阻断乳腺癌生长和转移的脂质代谢重编程。大学机构+早期体外/动物模型证据，靶点和赛道非热门领域导致总体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9106", "id": "TZ7ECZ0BZznHJdntvNYd", "source_drug_name": "Scd1 inhibitor", "title": "Scd1 overexpression in cancer-associated adipocytes drives breast cancer development and metastasis", "abstract_text": "Throughout the course of tumor development in breast cancer (BC), adipocytes within the tumor microenvironment undergo modifiable changes that promote tumor growth and invasive capacity, notably including the upregulation of Scd1, an enzyme integral to lipid metabolism. The timing of this metabolic reprogramming of healthy adipocytes to cancer-associated adipocytes (CAAs), as well as interventions that can reverse this process are poorly understood. To elucidate this progression, we used a polyoma middle T antigen (PyMT) transgenic mouse model that spontaneously develops luminal B-like tumors specific to the mammary fat pad (MFP). Using this model, we performed single-nucleus RNA sequencing (snRNA-seq) and metabolic profiling of MFP from healthy and tumor-bearing PyMT littermates. Among the many differences found when comparing healthy to tumor-bearing tissue at several time points throughout the progression of hyperplasia to invasive carcinoma, we discovered a consistent upregulation of Scd1, a stearoyl-CoA desaturase that performs the rate-limiting step in the conversion of saturated fatty acids (SFAs) to monounsaturated fatty acids (MUFAs), in adipocytes. However, despite the persistent upregulation of Scd1, we noticed an overall depletion of MUFAs in PyMT tumor-bearing tissue, indicating that tumor cells consume MUFAs during their malignant progression to invasive carcinoma and eventual metastasis. First, we recapitulated our snRNA-seq findings from mice in both snRNA-seq and spatial transcriptomics data from human breast tissue through gene signature scoring. We found that our progressive gene signatures accurately map to ductal carcinoma in situ, as well as invasive ductal carcinoma, providing confidence that interventions we establish in our mouse and in vitro models will translate to human BC. Next, to target the malignant transformation observed in our PyMT model, we cultured BC cell lines in adipocyte-conditioned medium, either when adipocyte Scd1 is selectively inhibited (iACM) or when adipocytes are allowed to function normally (ACM). Exposure to ACM alone increased cell viability, spheroid formation, and invasiveness, while iACM led to a marked decrease in all three parameters. Finally, to extend these results back into our mouse model, we injected C57BL/6 mice intracardially with BC cells conditioned in either ACM, iACM, or control media. While ACM led to aggressive metastasis with tropism selective for bone, iACM abolished the tropism and greatly decreased the metastatic capability of the injected cells. Taken together, our data show that the consistent upregulation of Scd1 throughout tumor progression in BC can be inhibited to reduce tumor growth and metastasis, thus identifying Scd1 expression in CAAs as a therapeutic target in BC, both in the early stages of progression and during metastatic spread.", "source_company": "UCI School of Medicine", "source_org_type": "大学", "row_number": 577, "target_meta": "SCD", "MOA_meta": "抑制剂"}, {"drug_name": "ASO targeting PD-1 pre-mRNA", "company": "Kawasaki Medical School", "org_type": "大学", "target": "PD-1 pre-mRNA", "modality": "ASO", "importance_level": "低", "total_score": 43.5, "institution_score": 25, "track_score": 75, "milestone_score": 35, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "通过靶向PD-1 pre-mRNA的ASO抑制PD-1表达以恢复T细胞抗肿瘤活性，目前仅在体外细胞系显示PD-1阳性比例下降，处于早期preclinical阶段。大学机构+preclinical初步数据导致整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5325", "id": "oVXM_5wBX1NQZOEH-LK6", "source_drug_name": "ASO targeting PD-1 pre-mRNA", "title": "Effects of antisense oligonucleotides targeting PD-1 pre-mRNA identified by DIRAC-dCas13-based screening on PD-1-positive lymphocytes", "abstract_text": "[Background and Purpose] In the tumor environment, T cells chronically express PD-1, and its interaction with PD-L1 on tumor cells results in decreased T cell cytokine secretion and proliferation. Exon2 of PD-1 encodes the PD-L1-binding domain. There have been few studies targeting RNA rather than the protein of PD-1 to upregulate lymphocyte antitumor immunity, especially the pre-mRNA region involved in Exon 2 splicing. We have recently reported that the region of PD-1 pre-mRNA was identified using the CRISPR/dCas13 system and a human CD8+ T cell line, and cytokine secretion capacity was maintained in the RNA region-targeted CD8+ T cells (PMID: 40920775). These findings were revealed in the presence of the idea that disrupting the interaction of the Exon2 splice cis-trans element on PD-1 pre-mRNA prevents the expression of the extracellular domain of PD-1, allowing lymphocytes to exert their inherent. In this presentation, we report on the effects on lymphocytes using a newly designed antisense oligonucleotides (ASO) derived from the identified pre-mRNA region of PD-1.\n[Materials and Methods] The designed PD-1 ASO sequences were based on the concept of the screening workflow of CLOVERNA Inc., and the ASO was provided by CLOVERNA Inc.. The ASO targeting PD-1 pre-mRNA was transduced into the human CD8+ T cell line, EBT-8 cells. The cells were maintained in GIT medium supplemented with recombinant human IL-2. Five days after transfection, the cells were harvested, and cell surface PD-1 expression was measured by flow cytometry.\n[Results] The new, unpublished data showed a decrease in the percentages of PD-1-positive cells of CD8+ T cells by the transfection with the ASO targeting PD-1 pre-mRNA.\n[Conclusion] This study revealed that the designed ASOs derived from the specific sequences of pre-mRNA identified using CRISPR/dCas13 contribute to suppressing PD-1 expression on the cell surface of human CD8+ T cells.\n[Future Plans] To assess tumor clearance capacity, we are in the preparation stage to begin in vitro cell-killing assays or in vivo PDX model experiments.", "source_company": "Kawasaki Medical School", "source_org_type": "大学", "row_number": 588, "target_meta": "PD1", "MOA_meta": "反义疗法"}, {"drug_name": "novel LPA1 antagonists", "company": "Lakehead University", "org_type": "大学", "target": "LPA1", "modality": "inhibitor", "importance_level": "低", "total_score": 43.5, "institution_score": 25, "track_score": 65, "milestone_score": 45, "field_heat_score": 55, "bonus_score": 0, "brief_reason": "靶向LPA1的拮抗剂作为migrastatics，旨在抑制TNBC细胞迁移侵袭而非增殖，机制新颖但处于早期发现阶段。大学机构研发、尚未进入体内疗效验证、整体临床转化潜力有限导致综合评分较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6283", "id": "F1XM_5wBX1NQZOEH-LO6", "source_drug_name": "novel LPA1 antagonists", "title": "LPA1 antagonists as potential migrastatics for triple negative breast cancer", "abstract_text": "Metastasis accounts for roughly 90% of cancer-related deaths. A new type of Anti-metastatic agents, known as migrastatics, offer a new therapeutic strategy that targets solely cancer cell migration and invasion while sparing proliferation. The FDA’s introduction of metastasis-free survival as a clinical endpoint in 2018 has created a regulatory framework that supports the development of such agents. By limiting cellular motility rather than inducing cytotoxic stress, migrastatics are expected to impose minimal selective pressure for the emergence of aggressive, drug-resistant subclones. Lysophosphatidic Acid Receptor 1 (LPA1), activated by the endogenous lipid LPA, is a key mediator of metastatic progression in triple-negative breast cancer (TNBC) and several other malignancies. We observed that LPA1 expression in MDA-MB-231 TNBC cells is at least 5-fold higher than in the non-malignant breast epithelial line MCF10A, supporting its role as a viable migrastatic target. Here, we report our medicinal chemistry efforts toward the discovery of novel LPA1 antagonists as potential migrastatic agents for TNBC. The lead compounds identified demonstrate high selectivity and potency, with IC₅₀ values ranging from 16.0 to 107 nM in a cAMP assay and no detectable activity at LPA2 or LPA3. These compounds suppress TNBC cell survival, migration, and invasion without inducing apoptosis or cytotoxicity. These findings are consistent with the mechanistic expectations of migrastatic therapy and support further preclinical development of LPA1-targeted agents for metastatic TNBC. In vivo efficacy and toxicity studies are currently underway.", "source_company": "Lakehead University", "source_org_type": "大学", "row_number": 665, "target_meta": "LPAR1", "MOA_meta": "抑制剂"}, {"drug_name": "α-MLT", "company": "Texas Tech University Health Sciences Center", "org_type": "大学", "target": "SLC6A14", "modality": "inhibitor", "importance_level": "低", "total_score": 43.5, "institution_score": 25, "track_score": 65, "milestone_score": 45, "field_heat_score": 50, "bonus_score": 0, "brief_reason": "α-MLT为SLC6A14小分子抑制剂，通过阻断氨基酸转运诱导PDAC营养缺乏，但联合HCQ抑制自噬/大吞噬作用以增强疗效。机构为大学非商业研发、处于动物模型验证阶段、靶点新颖但非热门赛道导致总体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9116", "id": "LlXM_5wBX1NQZOEH-LO6", "source_drug_name": "α-MLT", "title": "Dual targeting of SLC6A14 and autophagy/macropinocytosis enhances therapeutic efficacy in pancreatic ductal adenocarcinoma", "abstract_text": "PDAC is highly desmoplastic and undergoes metabolic reprogramming to sustain their growth and proliferation. Our laboratory has identified SLC6A14, an amino acid transporter, as a novel drug target for PDAC. Genetic deletion of SLC6A14 or its pharmacological blockade with α-MLT attenuates PDAC growth by inducing amino acid deprivation. However, nutrient stress, particularly amino acid deprivation, can induce nutrient scavenging mechanisms like autophagy and macropinocytosis, thereby undermining the full anticancer potential of SLC6A14 blockade. To address this, the current work was conducted to test if SLC6A14 blockade induces autophagy and/or macropinocytosis and to further investigate if dual inhibition of SLC6A14 (α-MLT) and autophagy/macropinocytosis (HCQ) would yield a better therapeutic outcome in PDAC as opposed to targeting SLC6A14 alone. In vitro assays (MTT and colony formation) revealed that the combination treatment significantly reduced PDAC cell viability and clonogenic potential as opposed to monotherapy. Treatment model subcutaneous xenograft in athymic nude mice demonstrated a superior therapeutic outcome with the combination regimen. Collectively, our study demonstrates that the afore-described combination therapy creates a metabolic trap wherein α-MLT induces nutrient stress, while HCQ prevents autophagic and macropinocytosis compensation, thus culminating in a more potent tumor attenuation. This dual blockade represents a hitherto unexplored treatment strategy for PDAC.", "source_company": "Texas Tech University Health Sciences Center", "source_org_type": "大学", "row_number": 683, "target_meta": "SLC6A14", "MOA_meta": "抑制剂"}, {"drug_name": "CXCR2 inhibitor", "company": "Huazhong University of Science and Technology Union Hospital Cancer Center", "org_type": "医院", "target": "CXCR2", "modality": "inhibitor", "importance_level": "低", "total_score": 43.5, "institution_score": 25, "track_score": 65, "milestone_score": 45, "field_heat_score": 50, "bonus_score": 0, "brief_reason": "CXCR2抑制剂通过阻断中性粒细胞IRG1/衣康酸轴阻断休眠肿瘤细胞苏醒及肺转移，机制新颖但仅为学术研究验证。机构为国内三甲医院附属肿瘤中心，非产业化主体且无明确临床开发里程碑，导致总体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6195", "id": "Yp7ECZ0BZznHJdntvNYd", "source_drug_name": "CXCR2 inhibitor", "title": "Tumor exosome-initiated neutrophil IRG1/itaconate axis awakens dormant tumor cells and promotes lung metastasis", "abstract_text": "Purpose/Objective(s): Tumor cell dormancy and metabolic reprogramming are critical events in metastatic relapse. However, the mechanisms, particularly how the lung pre-metastatic niche and its associated metabolic alterations awaken dormant disseminated tumor cells (DTCs), remain elusive. This study aims to decipher the cascade from primary tumor-derived exosomes to DTC reactivation in the pre-metastatic lung, specifically identifying the key metabolite-mediated pathway driving this process.\nMaterials/Methods: We employed multiple mouse models of spontaneous lung metastasis (e.g., B16-F10, Lewis). To comprehensively profile the pre-metastatic niche, we performed untargeted metabolomics on lung tissues to identify differentially enriched metabolites, and single-cell RNA sequencing (scRNA-seq) to delineate the cellular source of Irg1. Other key techniques included: in vivo imaging and H&E staining for metastasis tracking; generation of Irg1flox/flox mice with Mrp8-Cre for neutrophil-specific Irg1 deletion; RNA-seq of sorted alveolar macrophages; co-immunoprecipitation and Western blotting for itaconate-mediated LATS2 alkylation validation; chromatin immunoprecipitation (ChIP) for YAP1 nuclear translocation.\nResults: We delineated a sequential pathway driving metastatic reactivation in the lung. Initially, primary tumor-derived exosomes educated SPP1+ alveolar macrophages to bolster the production of CXCL2 and ensue neutrophil recruitment. Subsequently, these lung-infiltrating neutrophils specifically expressed Irg1, resulting in a marked accumulation of the metabolite itaconate within the pre-metastatic niche. Mechanistically, itaconate directly alkylated dormant DTCs at the C910 and C911 site of the key upstream kinase LATS2 in the Hippo pathway. This modification inhibited the LATS2’s capacity to phosphorylate YAP1, thereby promoting the nuclear translocation of unphosphorylated YAP1 to activate a pro-proliferative transcriptional program, forcing DTCs to exit dormancy. Crucially, this entire axis was disrupted by either neutrophil-specific genetic ablation of Irg1 or pharmacological inhibition of CXCR2, both of which significantly reduced tumor lung metastasis.\nConclusions: Our work unveils a novel paradigm in which the tumor exosome-neutrophil axis drives metastatic reactivation via metabolite-mediated protein alkylation. We pinpoint the neutrophil-IRG1-itaconate axis as a pivotal signaling cascade in this process, and our findings demonstrate that therapeutic targeting of this axis, either upstream at CXCR2 or at the metabolite itaconate, represents a viable strategy to prevent tumor lung metastasis.", "source_company": "Huazhong University of Science and Technology Union Hospital Cancer Center", "source_org_type": "医院", "row_number": 755, "target_meta": "CXCR2", "MOA_meta": "抑制剂"}, {"drug_name": "TBI-001", "company": "Gachon University", "org_type": "大学", "target": "TRIB2", "modality": "inhibitor", "importance_level": "低", "total_score": 43.5, "institution_score": 25, "track_score": 70, "milestone_score": 40, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "TBI-001为TRIB2选择性抑制剂，可降低免疫检查点表达并增强T细胞抗肿瘤活性，具有潜在双重机制。大学机构研发阶段为preclinical体外水平，无临床进展，赛道有一定热度但总体开发价值有限。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5275", "id": "QlXM_5wBX1NQZOEH-LS6", "source_drug_name": "TBI-001", "title": "TRIB2 regulates immune evasion in antiandrogen-resistant and neuroendocrine prostate cancer", "abstract_text": "Background: Enzalutamide resistance remains a major clinical challenge in advanced prostate cancer. We previously identified Tribbles homolog 2 (TRIB2) as highly upregulated in enzalutamide-resistant prostate cancer (ERPC), including neuroendocrine (NE)-type resistant tumors, where it drives tumor cell survival, lineage plasticity, and therapeutic resistance. Targeting TRIB2 suppresses the growth of resistant cells, highlighting its critical role in disease progression. Immune checkpoint molecules, including B7-H3 (CD276) and PD-L1 (CD274), are also elevated in ERPC and NE prostate tumors and contribute to impaired T cell-mediated anti-tumor immunity. These convergent findings led us to hypothesize that TRIB2 promotes immune evasion in treatment-resistant prostate cancer and that its inhibition may enhance T-cell-mediated anti-tumor immunity.\nMethods: Enzalutamide-resistant (C4-2BENZR and LNCaPENZR) and NE (NCI-H660) prostate cancer cell lines were used to investigate TRIB2-dependent immune regulation. TRIB2 expression was modulated using lentiviral shRNA knockdown, plasmid-mediated overexpression, or pharmacological inhibition using the selective TRIB2 inhibitor TBI-001. B7-H3 and PD-L1 expression was measured using western blot and flow cytometry. Modified cancer cells were co-cultured with activated human CD8⁺ T-cells, and T-cell activation, cytokine production, and cytotoxicity were evaluated using standard immunological assays.\nResults: Both TRIB2 knockdown and TBI-001 treatment markedly reduced B7-H3 and PD-L1 expression in ERPC and NE prostate cancer cells, whereas TRIB2 overexpression increased immune checkpoint levels. TRIB2 inhibition enhanced CD8⁺ T-cell activation and cytokine secretion (IFN-γ and TNF-α), and improved T cell-mediated cytotoxicity against resistant cancer cells. Conversely, cells with elevated TRIB2 levels strongly suppressed T-cell activation and cytotoxicity. Immune checkpoint blockade partially restored T-cell function against TRIB2-high cells, with combined blockade showing enhanced effects in restoring anti-tumor immunity.\nConclusion: These findings demonstrate that TRIB2 facilitates immune evasion in enzalutamide-resistant and neuroendocrine prostate cancer by upregulating immune checkpoint proteins and suppressing anti-tumor T-cell activity. This represents a dual mechanism by which TRIB2 drives treatment-resistant prostate cancer progression through both tumor-intrinsic effects and modulation of the tumor microenvironment. Therapeutic targeting of the TRIB2-immune checkpoint axis represents a rational strategy to overcome enzalutamide resistance, offering the combined benefit of inhibiting tumor growth while restoring effective anti-tumor immunity.", "source_company": "Gachon University", "source_org_type": "大学", "row_number": 877, "target_meta": "TRIB2", "MOA_meta": "抑制剂"}, {"drug_name": "fatty acid synthase (FASN) inhibitor", "company": "UT Health Science Center at San Antonio", "org_type": "大学", "target": "FASN", "modality": "inhibitor", "importance_level": "低", "total_score": 43.5, "institution_score": 35, "track_score": 60, "milestone_score": 35, "field_heat_score": 50, "bonus_score": 0, "brief_reason": "药物为FASN抑制剂，与化疗联合在体外显示协同杀伤CRC细胞，但仅为preclinical初步探索阶段。机构为大学，赛道为代谢靶点抑制剂（非当前最热门），整体临床转化里程碑价值有限。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5626", "id": "bVXM_5wBX1NQZOEH-LS6", "source_drug_name": "fatty acid synthase (FASN) inhibitor", "title": "Repurposed FDA-approved agents for hepatic artery infusion in colorectal liver metastases", "abstract_text": "Colorectal cancer (CRC) remains a leading cause of cancer-related death, with liver metastases (CRLM) representing the most common cause of mortality. Despite advances in systemic therapy, outcomes for patients with CRLM remain poor, underscoring a critical need for improved, liver-directed treatment strategies. Hepatic artery infusion (HAI) pumps are an effective method to deliver high local concentrations of chemotherapy directly to the liver while limiting systemic toxicity. The currently-standard of care compounds for HAI have limited efficacy and elevated hepatotoxicity, emphasizing the demand for treatment regimens that have better patient outcomes. In this project, we explored a drug repurposing strategy by evaluating FDA-approved chemotherapeutic agents with pharmacokinetic properties compatible with HAI delivery. Drugs were selected using established pharmacokinetic databases and then tested in vitro using CRC cell models and a normal epithelial liver cell line to assess cytotoxicity and dose-response. In addition, we investigated the therapeutic potential of combining a microtubule destabilizer with an FDA-approved fatty acid synthase (FASN) inhibitor. Synergy experiments demonstrated enhanced cytotoxic effects when chemotherapeutics were combined with the FASN inhibitor, suggesting that there is potential for a novel treatment regimen for patients presenting with this disease. These preliminary findings support drug repurposing within the context of HAI delivery as a clinically translatable approach. By utilizing existing FDA-approved compounds of both chemotherapeutic agents and metabolic inhibitors, this strategy may lay the groundwork for novel therapies for patients with CRLM. Further preclinical and translational studies will be necessary to define optimal drug combinations and dosing regimens, with the ultimate goal of expanding therapeutic options and improving outcomes for this high-risk patient population.", "source_company": "UT Health Science Center at San Antonio", "source_org_type": "大学", "row_number": 909, "target_meta": "FASN", "MOA_meta": "抑制剂"}, {"drug_name": "VC2-GM-CSF", "company": "Louisiana State University", "org_type": "大学", "target": "未披露", "modality": "oncolytic virus", "importance_level": "低", "total_score": 43.5, "institution_score": 30, "track_score": 65, "milestone_score": 40, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "VC2-GM-CSF为表达GM-CSF的溶瘤HSV-1病毒，通过溶瘤作用和免疫激活机制发挥抗肿瘤效应，但靶点未明确披露。机构为大学非商业化研发、处于动物模型阶段无临床进展，导致总体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9429", "id": "wFXM_5wBX1NQZOEH-LS6", "source_drug_name": "VC2-GM-CSF", "title": "Combinational effects of VC2-GMCSF oncolytic virus and paclitaxel in end-stage breast cancer animal model", "abstract_text": "Resistance and metastasis continue to make breast cancer a clinical challenge. VC2-GM-CSF drives antitumor immunity; paclitaxel remodels tumor environment to boost immune infiltration. Thus, combined use may yield superior therapeutic benefit over the use of either agent alone. This study investigates the potential synergistic interactions of VC2-GM-CSF with paclitaxel using the murine 4T1 breast cancer model in vitro and in vivo. In vitro, 4T1 cells were treated with paclitaxel alone or in combination with VC2-GM-CSF, and cell viability was assessed by MTT assay. Viral entry was quantified using a flow-cytometric assay. We further explored the in vivo antitumor effect of combined VC2-GM-CSF and paclitaxel in an orthotopic 4T1 stage IV metastatic model of breast cancer. Established 4T1 tumors in BALB/c mice were treated intratumorally with VC2-GM-CSF combined with paclitaxel. On day 31, tumors and lungs were collected for histopathological evaluation. Flow cytometric quantification of lymphocytes infiltrating the tumors was performed for CD45+, CD3+, CD4+, and CD8+ cells. The combined treatment was substantially more effective in inducing dose-dependent decreases in the viability of 4T1 cells and cell death than either single therapy in vitro. Flow cytometric entry assays showed that paclitaxel does not impair the entry of VC2-GM-CSF into cancer cells. In vivo, the combination significantly reduced primary tumor growth compared with the control treatment. Flow cytometry and immunohistochemistry analyses indicated increased T-cell infiltration in tumors after combination therapy. Together, these results demonstrate an enhanced antitumor effect resulting from the complementary cytotoxic and immunomodulatory mechanisms of paclitaxel and oncolytic virotherapy.", "source_company": "Louisiana State University", "source_org_type": "大学", "row_number": 974, "target_meta": "not available", "MOA_meta": "溶瘤病毒"}, {"drug_name": "SS-1-148", "company": "Northwestern University", "org_type": "大学", "target": "OAT", "modality": "inactivator", "importance_level": "低", "total_score": 43.5, "institution_score": 35, "track_score": 55, "milestone_score": 40, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "SS-1-148为新型OAT抑制剂，靶向鸟氨酸氨基转移酶以干扰HCC代谢重编程和多胺合成。大学早期preclinical阶段、OAT靶点非热门且modality非主流热门赛道，导致整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8903", "id": "M57M_5wBZznHJdnt_W3O", "source_drug_name": "SS-1-148", "title": "Targeting ornithine aminotransferase as a promising therapeutic strategy for hepatocellular carcinoma", "abstract_text": "Comprising 90% of all liver cancers, hepatocellular carcinoma (HCC) is the second leading cause of cancer-related death worldwide. Despite decades of research, prognosis remains poor: approximately 800,000 people are diagnosed with HCC each year, and ~80% die within five years. Therapeutically, there is a critical unmet need for more effective treatments. Resistance to sorafenib, the current first-line multi-target tyrosine kinase inhibitor, has become increasingly common. Moreover, more than 150 clinical trials evaluating targeted agents, immunotherapies, and combination regimens have failed due to insufficient efficacy, underscoring the urgent need for novel, mechanism-based therapeutic strategies. Emerging evidence highlights the central role of metabolic reprogramming in carcinogenesis, treatment resistance, and recurrence across multiple cancers, including HCC. Ornithine aminotransferase (OAT) is a key enzyme in this process, linking amino acid metabolism, particularly glutamine and proline, to polyamine biosynthesis and cancer cell proliferation. OAT is overexpressed in HCC and validated as a therapeutic target in preclinical models. We previously demonstrated that the OAT inactivator LHJ-2-79 effectively inhibits tumor growth in HepG2 and Hep3B xenografts and significantly suppresses alpha-fetoprotein (AFP) secretion, a key HCC biomarker, in Hep3B and HepG2 cells. However, no OAT inactivators have yet advanced to clinical trials. To address this gap, our laboratory recently synthesized SS-1-148, a novel OAT inactivator. Here, we report the effects of SS-1-148 on HCC using IC50 profiling, enzyme expression assays, xenograft survival studies, RNA-seq analysis, and metabolomic data. Our findings reveal cell line-dependent differences in SS-1-148 potency, OAT activity inhibition, tumor growth suppression, metabolic gene expression, and alterations in proline and polyamine levels. In vivo, SS-1-148 inhibited Huh-7 xenograft growth but not Huh-6 tumors. Metabolomic analyses of LHJ-2-79 and SS-1-148 in Huh-6 and Huh-7 cells further demonstrated distinct effects on proline and putrescine levels, suggesting different mechanisms of action between the two inactivators. Collectively, these results support OAT as a promising therapeutic target in HCC and lay the foundation for further development of OAT-based treatment strategies.", "source_company": "Northwestern University", "source_org_type": "大学", "row_number": 983, "target_meta": "OAT,OAT", "MOA_meta": "其他"}, {"drug_name": "CMLD2", "company": "All India Institute of Medical Sciences New Delhi", "org_type": "医院", "target": "HuR", "modality": "inhibitor", "importance_level": "低", "total_score": 43.5, "institution_score": 25, "track_score": 65, "milestone_score": 45, "field_heat_score": 50, "bonus_score": 0, "brief_reason": "CMLD2为HuR（ELAVL1）的高选择性小分子抑制剂，针对TNBC显示出较好的体外和体内抑制肿瘤作用。机构为医院/研究型，开发阶段仍处preclinical，赛道非热门，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3858", "id": "6Z7M_5wBZznHJdnt_W3O", "source_drug_name": "CMLD2", "title": "Therapeutic targeting of HuR using a specific small-molecule inhibitor in triple negative breast cancer", "abstract_text": "Human Antigen R (HuR/ELAVL1) is an RNA-binding protein that interacts with U/AU-rich elements in target mRNAs, and its aberrant cytoplasmic accumulation have been observed in multiple cancers. HuR modulates the expression of key oncogenic and survival-related transcripts, thereby driving tumor progression, metastasis, and therapeutic resistance. Given this central role, HuR represents a compelling molecular target for cancer therapy. The present study specifically evaluates the potential of CMLD2, a highly selective small-molecule inhibitor of HuR, in the context of Triple-Negative Breast Cancer (TNBC). Comparative assessments were conducted using CMLD2 and DHTS across in silico and in vitro models. Immunohistochemical analysis of 71 TNBC samples revealed HuR overexpression in 66% of cases, along with elevated expression of HuR downstream target MMP9 (56%). Furthermore, in silico analysis established significant association between HuR overexpression and poor patient survival (p = 0.028). Functional assays in TNBC cell lines MDA-MB-231 and MDA-MB-468 demonstrated that both inhibitors suppressed proliferation, invasion, and clonogenicity; however, CMLD2 exhibited markedly higher specificity and consistency in inhibiting HuR function. Mechanistically, CMLD2 treatment downregulated HuR and its downstream effectors MMP9 and β-catenin, while reversing epithelial-mesenchymal transition (EMT) marker expression (E-cadherin, N-cadherin and Vimentin). Immunofluorescence and cell fractionation confirmed effective cytoplasmic HuR inhibition. Moreover, CMLD2 distinctly suppressed aerobic glycolysis, evidenced by reduced extracellular acidification and downregulation of key glycolytic mediators—PFKP, LDHA, and MCT4—validated at both transcript and protein levels. HuR silencing by siRNA supported the role of HuR in glycolytic regulation and TNBC progression. In vivo, CMLD2 significantly impaired tumor-forming ability in female BALB/c mice. Together, these findings underscore the therapeutic promise of CMLD2 as a specific and potent HuR inhibitor, providing strong experimental rationale for its further development as a targeted intervention in Triple-Negative Breast Cancer.", "source_company": "All India Institute of Medical Sciences New Delhi", "source_org_type": "医院", "row_number": 1114, "target_meta": "ELAVL1", "MOA_meta": "抑制剂"}, {"drug_name": "WNK1 inhibitor", "company": "Case Western Reserve University", "org_type": "大学", "target": "WNK1", "modality": "inhibitor", "importance_level": "低", "total_score": 43.5, "institution_score": 25, "track_score": 65, "milestone_score": 45, "field_heat_score": 55, "bonus_score": 0, "brief_reason": "WNK1抑制剂通过解除对MEK-ERK通路的抑制促进C/EBPβ活性及AML细胞粒系分化，与ATRA协同作用。机构为大学、处于preclinical阶段、无明显机制创新亮点导致总分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5636", "id": "AJ7M_5wBZznHJdnt_W7O", "source_drug_name": "WNK1 inhibitor", "title": "Anti-leukemic effects of WNK1 inhibition are enhanced by combination with ATRA in AML", "abstract_text": "Impaired differentiation is a key pathological feature of Acute Myeloid Leukemia (AML). AML differentiation-inducing agents such as all-trans retinoic acid (ATRA) have shown great promise to treat AML patients as seen by improved overall survival and relapse rates. However, this success has been limited to a subset of AML patients, namely those with Acute Promyelocytic Leukemia (APL). This highlights the need to identify more differentiation therapy options that could be effective for other AML subtypes. In this study, we identified With-no-Lysine(K) kinase 1 (WNK1) as a novel regulator of AML differentiation arrest. We show evidence of WNK1 dysregulation in AML patients demonstrated by its increased expression and activity compared to healthy controls. Targeting WNK1 through genetic or pharmacologic inhibition induced granulocytic differentiation of AML cell lines in vitro. WNK1 inhibition also caused cell cycle arrest and apoptosis. Furthermore, oral administration of WNK1 inhibitor reduced leukemic burden in AML xenograft models. We observed that knocking down expression of WNK1 substrates SPAK and OSR1 mirrored the effects of WNK1 inhibition suggesting their involvement in mediating pro-leukemic functions of WNK1. Mechanistically, we show that WNK1 inhibition induces differentiation by promoting MEK-ERK activity and increasing C/EBPβ activity and expression, resulting in increased transcription of myeloid differentiation genes. Finally, we illustrate that combining WNK1 inhibition with ATRA further boosts ATRA’s efficacy, synergistically increasing differentiation, apoptosis, and cell cycle arrest. C/EBPβ expression was also enhanced by this combination treatment, suggesting a role for C/EBPβ in mediating these anti-leukemic effects. Taken together, our findings suggest that WNK1 negatively regulates ERK phosphorylation and activity, likely through SPAK/OSR1. Inhibiting WNK1 releases ERK suppression, increasing C/EBPβ activity and expression which leads to myeloid differentiation. Overall, our findings reveal a novel role for WNK1 in promoting differentiation arrest and highlight its potential as a new therapeutic target for AML treatment.", "source_company": "Case Western Reserve University", "source_org_type": "大学", "row_number": 1130, "target_meta": "WNK1", "MOA_meta": "抑制剂"}, {"drug_name": "PD-L1 blockade", "company": "University of Virginia School of Medicine", "org_type": "大学", "target": "PD-L1", "modality": "inhibitor", "importance_level": "低", "total_score": 43.5, "institution_score": 25, "track_score": 75, "milestone_score": 35, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "靶点为PD-L1，属于经典免疫检查点抑制机制，但摘要聚焦于卵巢癌免疫治疗抵抗的机制研究而非药物本身开发。机构为大学，处于preclinical探索阶段，无明确药物里程碑，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5463", "id": "sZ3ECZ0B4z9FlvORyiZD", "source_drug_name": "PD-L1 blockade", "title": "Investigating how host TLR5 signaling modulates FLT3 ligand therapeutic efficacy for ovarian cancer", "abstract_text": "Ovarian cancer continues to be the most fatal gynecological malignancy, and survival rates of individuals with this disease have remained relatively unchanged for the past 30 years. Though immunotherapies such as immune checkpoint blockades have drastically improved survival outcomes for other cancers, they rarely induce a therapeutic response for ovarian cancer. We have identified toll-like receptor 5 (TLR5) signaling, the only known ligand of which is bacterial flagellin, as a host- intrinsic factor that orchestrates the failure of checkpoint therapy for ovarian cancer. Mechanistically, ovarian tumors induce chronic gut leakage, enabling dissemination of flagellin into the ovarian tumor microenvironment (TME). Chronic TLR5 signaling disrupts the accumulation of IL-12+ anti-tumorigenic dendritic cells (DCs) in the ovarian TME and promotes expansion of PD-L1 expressing immature myeloid populations, culminating in failure of immune checkpoint blockade. One strategy to overcome this deficit is to promote further expansion of DCs via administration of the DC growth factor fms-like tyrosine kinase receptor 3 ligand (FLT3L). Although no benefit was observed for wild type (WT) mice with intact TLR5 signaling, an observation consistent with poor clinical efficacy of FLT3L therapy, FLT3L administration in TLR5-deficient (TLR5KO) mice resulted in prolonged and durable survival for over 80% of animals when combined with PD-L1 blockade. These data suggest that in the absence of TLR5 signaling, the ovarian TME becomes more responsive to immunotherapy, and justifies further investigation into how TLR5 signaling is disrupting FLT3L expanded DCs. High dimensional flow cytometry data show that in the absence of ovarian tumors, FLT3L significantly expands the proportion of DCs in multiple tissues, including the peritoneal cavity, in both TLR5KO and WT mice. Phenotypic profiling of tumor nodules and the peritoneal cavity in ovarian tumor- bearing TLR5KO and WT animals 24 hours after FLT3L treatment ceases shows significantly higher frequencies of DCs in the peritoneal cavity of TLR5KO mice as compared to WT. Analysis of tumor nodules also reflects a significant increase in the frequency of dendritic cells infiltrating tumors as compared to WT mice. These preliminary results suggest TLR5 signaling is impacting the expansion and/or recruitment of dendritic cells into the ovarian tumor microenvironment. Ongoing and future experiments will assess chemokines and cytokines the periphery, peritoneal washes, and tumor lysates to define TLR5-mediated signaling pathways that inhibit DC maturation and recruitment. Our results aim to mechanistically define how chronic TLR5 signaling is impacting FLT3L efficacy, and further elucidate how TLR5 signaling is a host intrinsic process whereby the microbiome is driving resistance to immune therapies.", "source_company": "University of Virginia School of Medicine", "source_org_type": "大学", "row_number": 1152, "target_meta": "PDL1", "MOA_meta": "抑制剂"}, {"drug_name": "PARP inhibitors", "company": "Center for Prostate Disease Research", "org_type": "研究机构", "target": "未披露", "modality": "inhibitor", "importance_level": "低", "total_score": 43.5, "institution_score": 25, "track_score": 75, "milestone_score": 35, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "研究使用FDA批准的PARP抑制剂探索RAD21过表达对Ewing肉瘤和前列腺癌DNA损伤修复及PARPi敏感性的影响，靶点为PARP但非新药开发。机构为研究机构且仅为机制探索，无明确药物推进里程碑，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4831", "id": "Yp7M_5wBZznHJdnt_W7P", "source_drug_name": "PARP inhibitors", "title": "Effects of aneuploidy associated RAD21 gain on therapeutic response to PARP inhibition in Ewing sarcoma and prostate cancer", "abstract_text": "Chromosome 8 (chr8) gain, particularly the gain of its long arm 8q, represents one of the most frequent chromosomal abnormalities across multiple human cancers. In Ewing sarcoma, approximately 50% of cases exhibit chr8 gain while in prostate cancer, high level amplification of 8q occurs in about 24% of primary cases with much higher frequencies in metastatic cases. Across both diseases, the cohesin subunit gene RAD21, located on 8q24.11 region, has emerged as a key driver that facilitates chr8 gain by alleviating replication stress associated with oncogene activation. RAD21 is a highly conserved protein essential for establishing sister chromatid cohesin, chromatin looping, DNA replication, transcriptional regulation, and DNA damage repair. Our recent study demonstrated that elevated RAD21 expression correlates with increased cancer-specific mortality in prostate cancer, underscoring its potential role in tumor progression. However, how RAD21 mitigates replication-stress-associated DNA damage and modulates therapeutic response remains poorly understood. To address this gap, we investigated RAD21’s role in the DNA damage response (DDR) and treatment resistance using Ewing sarcoma and prostate cancer cell models. Using TurboID-based protein proximity labeling and mass spectrometry, we have demonstrated that RAD21 interacts with several key DNA damage initiating factors upon oncogenic induction including PARP1 and MRE11, suggesting that RAD21 engages with DNA repair initiating and homologous recombination (HR)-associated machinery. Given the clinical use of DNA damage-inducing PARP inhibitors (PARPi) for targeting HR-deficient cancers, we evaluated FDA-approved PARPi in isogenic Ewing sarcoma and prostate cancer cell models engineered to express distinct levels of RAD21. Our data showed that RAD21 overexpression markedly altered the cellular response to PARP inhibition in both models and this effect appears to be independent from cell-cycle regulation, consistent with a potential role for RAD21 enhancing HR-mediated DNA repair. In summary, our findings reveal an often overlooked function of RAD21 in altering DNA repair and influencing the response to therapeutic drugs targeting DNA repair pathways. Dysregulation of cohesin could contribute to therapeutic resistance and a potential biomarker for stratifying patients for DDR-targeted treatments.", "source_company": "Center for Prostate Disease Research", "source_org_type": "研究机构", "row_number": 1188, "target_meta": "not available", "MOA_meta": "抑制剂"}, {"drug_name": "ferroptosis inducers", "company": "Tata Memorial Centre-Advanced Centre for Treatment, Research and Education in Cancer (TMC-ACTREC) and HBNI", "org_type": "研究机构", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 43.5, "institution_score": 25, "track_score": 75, "milestone_score": 35, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "摘要聚焦Galectin-1调控EMT和铁死亡抑制机制，ferroptosis inducers作为潜在治疗干预，但未明确具体药物靶点或候选化合物，仅为研究机构preclinical机制探索。机构非商业头部、开发阶段早期导致总体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4597", "id": "gJ7M_5wBZznHJdnt_W7P", "source_drug_name": "ferroptosis inducers", "title": "Chemotherapy-induced galectin-1 derives drug-tolerant persister state associated EMT in triple negative breast cancer with targetable vulnerability to ferroptosis inducers", "abstract_text": "Triple-Negative Breast Cancer (TNBC) is the most aggressive and difficult-to-treat disease with high mortality rates. Therapeutic challenges are largely due to limited treatment options, disease heterogeneity, drug resistance, and metastasis to vital organs. Clinical studies established that non-genetic alterations derive chemoresistance and metastasis in TNBC. however, experimental studies investigating residual disease and metastatic recurrence in TNBC are limited. We derived subtype-specific TNBC Drug-Tolerant Persister (DTP) cellular models using taxol and platinum drugs and longitudinally characterized parental, mitotically quiescent and proliferating DTP cellular states to study the molecular basis of post-treatment aggressiveness. We observed that therapeutic agents induced autophagy and dysregulation of ferroptosis regulators including GPX4 and FSP1, irrespective of subtype and EMT largely in basal and luminal androgen receptor-positive TNBC cells. Since these phenotypes are known to be regulated by both intra- and extra-cellular signaling factors we profiled for differentially expressed soluble intracellular and secretome proteome in TNBC DTP cells using label-free quantitative mass spectrometry. Interestingly, we found that soluble factors IGFBP6, SERPINE1 and LGALS1 were among the most upregulated proteins in extracellular protein fractions of DTP cells, LGALS1 was also found significantly high in the cellular fraction. Integrative in-silico analysis of survival and expression data of TNBC patients under treatment accentuated that LGALS1 (Galectin-1) has strong clinical association with adverse prognosis and co-expression with EMT and ferroptosis-related genes. Further, conditioned medium experiment revealed that secretome from proliferating TNBC DTPs was capable of conferring multiple aggressive phenotypes including EMT, migration, invasion, proliferation, antioxidant pathway deregulation, autophagy in parental TNBC cells. These changes were collaborated with an increased activation of pSTAT3, pSrc and MAP kinase signaling pathways. Moreover, genetic and pharmacological targeting of Galectin-1 in TNBC DTP cells significantly attenuation proliferation, EMT, migration and invasion properties, with an increased susceptibility to ferroptosis inducers. Further, Galectin-1 knockdown resulted in downregulation of GPX-4 and FSP-1 in a NRF2-dependent manner, highlighting the therapeutic potential of targeting Galectin-1 in controlling EMT and inducing ferroptotic cell death. Most importantly, considering that tumor-secreted Galectin-1 can be detected in the blood it may serve as a theranostic biomarker for therapy resistance and poor prognosis as well as potential therapeutic target for overcoming chemo-tolerance and metastasis in TNBC patients.", "source_company": "Tata Memorial Centre-Advanced Centre for Treatment, Research and Education in Cancer (TMC-ACTREC) and HBNI", "source_org_type": "研究机构", "row_number": 1211, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "anti-PD1", "company": "The Ohio State University", "org_type": "大学", "target": "PD-1", "modality": "inhibitor", "importance_level": "低", "total_score": 43, "institution_score": 25, "track_score": 80, "milestone_score": 30, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "anti-PD1为经典PD-1抑制剂，但本摘要仅作为已上市对照药用于研究肠道菌群对ICI疗效的影响，而非新药开发。大学机构+无新药里程碑导致整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1280", "id": "f1XM_5wBX1NQZOEH-LK6", "source_drug_name": "anti-PD1", "title": "Comparative genomics of gut commensal Lachnospiraceae and their associations with cancer treatment response with immune checkpoint inhibitors", "abstract_text": "Immune checkpoint inhibitors (ICIs) are seminal advances in cancer therapeutics, yet response rates are variable. The gut microbiome is increasingly recognized as a modifiable determinant of ICI efficacy. The BEWELL trial delivered a black raspberry (BRB) nectar dietary intervention that significantly enriched the colonic microbiome with members of the Lachnospiraceae family. When BRB-modulated microbiomes were transferred into mice, these microbiomes enhanced ICI antitumor activity, implicating specific taxa in shaping therapeutic responsiveness.To investigate the mechanism by which Lachnospiraceae altered ICI effectiveness, we individually supplemented the microbiomes of mice with closely related strains enriched by BRB: Blautia obeum, Blautia massiliensis, and Agathobacter rectalis. In a heterotopic mouse model (1×10⁶ MC38 cells injected subcutaneously into C57BL/6 mice, treated every 3 days with anti-PD1 or IgG), B. obeum and B. massiliensis improved ICI effectiveness, whereas A. rectalis did not. We compared the genomes of these organisms and identified 177 KEGG orthologs uniquely shared by B. obeum and B. massiliensis but absent in A. rectalis. KO pathway assignments and enrichment analyses were conducted using KEGGREST mapping and clusterProfiler overrepresentation testing, with all genome-encoded KOs as the background.We identified four relevant pathways associated with immunity and ICI response:(1) Key genes for the Wood-Ljungdahl pathway, a major route for producing acetate, shown to be a T-cell energy source (acetyl-CoA decarbonylase/synthase (K00194, K00197, K00198) and putative phosphotransacetylase (K01490));(2) Genes for synthesizing vitamins essential for T-cell proliferation—folate (B9) (dihydropteroate synthase (K00796), GTP cyclohydrolase I (K022391), methylenetetrahydrofolate reductase (K00297)) and cobalamin (B12) (cob(I)alamin adenosyltransferase (K019221), corrinoid adenosyltransferase (K0174), cobalamin reductase (K0175));(3) L-rhamnose synthesis genes whose cell-wall decorations act as microbe-associated molecular patterns, priming innate immunity (dTDP-4-dehydrorhamnose reductase (K00067) and dTDP-glucose 4,6-dehydratase (K00935)); and(4) Genes converting bile acids to secondary, iso-bile acids that interact with host receptors (FXR, TGR5) to regulate Th17/Treg balance (3-alpha-hydroxycholanate dehydrogenase (K0164))\nCollectively, these processes align with host-relevant metabolic and signaling environments that may impact anti-tumor immunity. Our study suggests that novel food products can be developed for human testing to enhance anticancer immunotherapeutics. Furthermore, BRB-responsive Lachnospiraceae possess enriched metabolic and immunomodulatory gene programs that may underlie their association with improved tumor response to ICI treatment.", "source_company": "The Ohio State University", "source_org_type": "大学", "row_number": 568, "target_meta": "PD1", "MOA_meta": "抑制剂"}, {"drug_name": "HIF2a inhibitor", "company": "Vanderbilt-Ingram Cancer Center", "org_type": "医院", "target": "HIF2a", "modality": "inhibitor", "importance_level": "低", "total_score": 43, "institution_score": 30, "track_score": 85, "milestone_score": 20, "field_heat_score": 70, "bonus_score": 0, "brief_reason": "药品靶向HIF2a（即HIF-2α），这是在肾细胞癌尤其是透明细胞型中关键驱动靶点，属于热门小分子抑制剂赛道。机构为医院/学术中心而非药企，无具体药物名称、开发阶段或里程碑数据披露，导致整体研发推进价值有限。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/226", "id": "4VXM_5wBX1NQZOEH-LO6", "source_drug_name": "HIF2a inhibitor", "title": "Clinical advances with HIF2a targeting in sporadic renal cell carcinoma", "abstract_text": "There is no abstract associated with this presentation.", "source_company": "Vanderbilt-Ingram Cancer Center", "source_org_type": "医院", "row_number": 809, "target_meta": "HIF-2α", "MOA_meta": "抑制剂"}, {"drug_name": "Brusatol", "company": "All India Institute of Medical Sciences (AIIMS) New Delhi", "org_type": "医院", "target": "NRF2", "modality": "inhibitor", "importance_level": "低", "total_score": 43, "institution_score": 30, "track_score": 70, "milestone_score": 40, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "Brusatol为天然化合物来源的NRF2抑制剂，通过抑制NRF2驱动的抗氧化防御和EMT逆转在宫颈癌细胞中发挥抗肿瘤作用。机构为医院/研究型，preclinical阶段仅细胞水平验证，无公司推动开发，赛道虽涉及热门抗氧化靶点但整体热度和开发潜力有限。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3468", "id": "f57M_5wBZznHJdnt_W3O", "source_drug_name": "Brusatol", "title": "Inhibition of NRF2 driven antioxidant defence and EMT underlies brusatol induced cytotoxicity in cervical cancer cells", "abstract_text": "Cervical cancer remains a major global health burden, and its therapeutic resistance is strongly influenced by redox adaptation, epithelial-mesenchymal transition (EMT), and metabolic reprogramming. Brusatol, a natural quassinoid compound, is known for its ability to suppress NRF2-driven antioxidant defense mechanisms. However, its mechanistic impact on cervical cancer has not been fully characterized.In this study, we first employed quantitative proteomic profiling to obtain an unbiased overview of Brusatol-induced molecular alterations. Proteomics analysis revealed extensive downregulation of proteins associated with antioxidant defense, glycolysis, cytoskeletal organization, and EMT regulation. Conversely, proteins linked to oxidative stress responses, mitochondrial dysfunction, and apoptotic signalling were significantly upregulated. Pathway enrichment analysis confirmed inhibition of glycolytic and redox-regulatory pathways, suppression of cell motility networks, and activation of oxidative stress driven cytotoxic processes.These global proteomic signatures were further substantiated through western blot validation, which demonstrated reduced expression of key components involved in antioxidant defense and EMT regulation following Brusatol treatment. Western blot analysis also showed suppression of glycolytic markers, supporting the proteomics-predicted metabolic disruption.Functionally, Brusatol significantly reduced proliferation, induced apoptosis, suppressed migration, and reversed EMT characteristics in cervical cancer cell lines. Treated cells exhibited decreased mesenchymal marker expression, restoration of epithelial traits, reduced glucose uptake, and impaired glycolytic activity. Importantly, a non-tumorigenic epithelial cell line showed substantially lower sensitivity, indicating selective cytotoxicity toward cancer cells.\nTogether, these findings demonstrate that Brusatol exerts potent anti-tumor effects in cervical cancer by initiating widespread proteomic reprogramming, suppressing NRF2-linked antioxidant pathways, reversing EMT, and disrupting glycolytic metabolism. The integration of proteomic profiling with biochemical validation and functional assays provides strong mechanistic evidence supporting brusatol as a promising therapeutic candidate for overcoming treatment resistance in cervical cancer.", "source_company": "All India Institute of Medical Sciences (AIIMS) New Delhi\nAll India Institute of Medical Sciences (AIIMS)", "source_org_type": "医院", "row_number": 1035, "target_meta": "Nrf2", "MOA_meta": "抑制剂"}, {"drug_name": "Immune Checkpoint Blockade", "company": "Vanderbilt University Medical Center", "org_type": "医院", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 42.5, "institution_score": 25, "track_score": 70, "milestone_score": 30, "field_heat_score": 65, "bonus_score": 0, "brief_reason": "该条目并非具体药品开发，而是针对晚期胃癌ICB疗效的空间转录组生物标志物研究，未披露特定药物靶点。机构为医院类，赛道为热门免疫治疗但无药物里程碑，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10034", "id": "a1XM_5wBX1NQZOEH-LG5", "source_drug_name": "Immune Checkpoint Blockade", "title": "Spatially derived transcriptomic predictors of immune checkpoint blockade outcome in advance gastric cancer", "abstract_text": "Background: Advanced gastric cancer (GC) responds poorly to systemic therapy, including Immune Checkpoint Blockade (ICB), yet how the tumor microenvironment (TME) drives resistance remains unknown. We assembled the largest spatial transcriptomic dataset in Immune Checkpoint Blockade (ICB)-treated GC, derived signatures encoding spatial composition and their cellular functions and phenotypes, and validated these as outcome predictors across bulk, single-cell, and independent spatial cohorts.\nMethods: Pre-treatment samples from advanced GC patients receiving ICB were profiled using spatial transcriptomics to derive spatial signatures that deconvolve immune, stromal, and tumor compartments and capture TME niches associated with ICB non-response. These spatial signatures were projected onto multiple external datasets, including four bulk RNA-seq cohorts, one single-cell RNA-seq cohort, two 10x Visium cohorts (27 GC samples), and one proteomic cohort, representing the largest integrated validation set for GC immunotherapy biomarkers to date.\nResults: Spatial immune signatures in non-responders showed Th2, regulatory Th17, and a homing-lymphocytes program marked by VLA-4 and CXCR4, confirmed in scRNA-seq. Stromal signatures in non-responders included inflammatory CAF programs, complement system activation (C1S, C3, A2M, IL6ST), growth-factor signaling, and MHC-II antigen-presenting states. When projected onto bulk RNA-seq and proteomic cohorts, these spatial immune and stromal modules were consistently enriched in clinical non-responders and associated with inferior survival. In 10x Visium data, non-responder stroma exhibited a strong complement system, aligned with ECM remodeling and myofibroblast properties, and showed reduced neighboring T-cell infiltration. Spatial bivariate analyses localized MHC genes and M2-like C1q⁺ macrophages to inflamed stromal niches. Additional non-responders, including an MSI-H case, retained Th2-dominant profiles, whereas responders revealed higher tumor-antigen expression and dendritic-cell activation.\nConclusion: Spatially derived transcriptomic signatures that incorporate functional states of the GC immune microenvironment robustly distinguish ICB non-responders across bulk, single-cell, and independent spatial datasets. These data nominate the inflammatory stromal niches, C1q⁺ macrophage clusters, and skewed Th2 as actionable features of ICB resistance and potential therapeutic targets. Our results support incorporating spatial transcriptomics into pre-treatment assessment to refine patient selection, prioritize combination strategies that remodel the stromal-immune interface, and advance toward clinically deployable, GC-specific biomarkers for immunotherapy.\nAI was used for language editing only; authors are responsible for all content and approved the final version.", "source_company": "Vanderbilt University Medical Center", "source_org_type": "医院", "row_number": 14, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "siR-PTBP1", "company": "Gifu University", "org_type": "大学", "target": "PTBP1", "modality": "siRNA", "importance_level": "低", "total_score": 42.5, "institution_score": 35, "track_score": 65, "milestone_score": 30, "field_heat_score": 55, "bonus_score": 0, "brief_reason": "siR-PTBP1靶向PTBP1通过调控PKM剪接诱导胃癌细胞代谢重编程和凋亡，属于核酸药物范畴。大学早期体外研究，preclinical阶段较浅、机构非产业化主体，导致总体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6553", "id": "o1XM_5wBX1NQZOEH-LG6", "source_drug_name": "siR-PTBP1", "title": "PTBP1-targeted siRNA reprograms cellular metabolism and induces apoptosis in human gastric cancer cells", "abstract_text": "Background: The prognosis of advanced gastric cancer remains poor despite recent therapeutic progress, underscoring the need for novel strategies. Cancer cells commonly rely on aerobic glycolysis (the Warburg effect). PTBP1 contributes to this metabolic phenotype by regulating the alternative splicing of the PKM gene, suppressing PKM1 and promoting the PKM2 isoform, which supports glycolytic metabolism. We hypothesized that PTBP1 inhibition would suppress tumor growth by shifting metabolic flux toward oxidative phosphorylation.\nMethods: Thirteen chemically modified siR-PTBP1 derivatives were synthesized and tested in the gastric cancer cell line MKN1. Cell viability was measured by crystal violet staining. PTBP1 expression, PKM1/PKM2 isoform switching, ATP production, and apoptosis (cleaved PARP) were evaluated by Western blotting and ATP assay.\nResults: Optimized siR-PTBP1 selectively reduced PTBP1 expression and increased the PKM1/PKM2 ratio, indicating metabolic reprogramming. ATP assay demonstrated that siR-PTBP1 treatment increased intracellular ATP production, supporting a metabolic shift from glycolysis toward oxidative phosphorylation. These metabolic changes were accompanied by elevated cleaved PARP levels, consistent with apoptosis induction. Consequently, siR-PTBP1 significantly inhibited MKN1 cell proliferation.\nConclusion: PTBP1 inhibition reprograms tumor metabolic pathways and triggers apoptosis in gastric cancer cells. siR-PTBP1 represents a promising metabolism-targeted nucleic acid therapeutic candidate, warranting further evaluation in in vivo xenograft models.", "source_company": "Gifu University", "source_org_type": "大学", "row_number": 424, "target_meta": "PTBP1", "MOA_meta": "其他"}, {"drug_name": "mutual prodrug liposomes (co-delivering all-trans retinoic acid and a quinone methide precursor)", "company": "Jeonbuk National Univ.", "org_type": "大学", "target": "PIN1", "modality": "other", "importance_level": "低", "total_score": 42.5, "institution_score": 25, "track_score": 65, "milestone_score": 45, "field_heat_score": 50, "bonus_score": 3, "brief_reason": "药物通过互助前药脂质体形式共递送atRA与QM前体，实现PIN1抑制与氧化应激放大协同抗癌，靶向PIN1并破坏肿瘤氧化还原稳态。大学机构+处于体外+体内动物模型的preclinical阶段，整体创新性较好但缺乏头部药企推动与临床转化迹象，重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5566", "id": "RZ7ECZ0BZznHJdntvNYd", "source_drug_name": "mutual prodrug liposomes (co-delivering all-trans retinoic acid and a quinone methide precursor)", "title": "Self-synergizing mutual prodrug liposomes co-targeting redox homeostasis and PIN1 for cancer therapy", "abstract_text": "PIN1 is a prolyl isomerase that catalyzes the cis-trans isomerization of phosphorylated Ser/Thr-Pro motifs and is overexpressed in various cancer types, where it functions as a key regulator that amplifies oncogenic signaling. PIN1 promotes cancer cell proliferation, survival, and metastasis by stabilizing diverse oncoproteins and disrupting tumor-suppressive pathways such as p53, and its activity is highly sensitive to the intracellular redox state, becoming inactivated in a redox-dependent manner in response to changes in oxidative stress levels. In this study, we developed a mutual prodrug in which all-trans retinoic acid (atRA) is integrated into a single molecule with a quinone methide (QM) precursor that amplifies oxidative stress via glutathione (GSH) depletion, to simultaneously maximize atRA-mediated PIN1 inhibition and reactive oxygen species (ROS)-mediated anticancer activity. We first evaluated the synergistic cytotoxicity of atRA and the QM precursor in MCF-7 breast cancer cells by calculating the combination index and assessing changes in PIN1 and its downstream effector cyclin D1 by Western blotting. To exploit this synergy, we designed and synthesized a mutual prodrug in which atRA is covalently linked to the QM precursor, and confirmed its structure by 1H NMR and LC-MS/MS analysis. Owing to its amphiphilic molecular structure, the mutual prodrug could be stably incorporated into the lipid bilayer at a high loading (~40%) together with DPPC, which enabled the formulation of prodrug-based liposomes. The liposomal surface was subsequently coated with γ-poly(glutamic acid) (γPGA) targeting γ-glutamyl transferase (GGT), yielding particles with a mean diameter of approximately 150 nm. We then examined esterase-triggered release of atRA and QM and evaluated intracellular GSH depletion and ROS amplification, as well as mitochondrial dysfunction, in MCF-7 cells. We further analyzed redox-responsive, PIN1-related, and apoptosis-related signaling by qPCR and Western blotting. Targeting and in vivo antitumor efficacy of the γPGA-coated prodrug liposomes were assessed in an MCF-7 xenograft mouse model, and additional biosafety evaluation revealed no apparent systematic toxicity. Collectively, the mutual prodrug liposomal formulation integrating atRA and the QM precursor disrupted intracellular redox homeostasis and suppressed PIN1-dependent oncogenic signaling, resulting in enhanced anticancer efficacy and reduced systematic toxicity. Thus, this platform offers a next-generation precision nanomedicine candidate that unifies high drug loading, tumor-selective delivery, and self-synergistic mechanisms within a single, clinically translatable system.", "source_company": "Jeonbuk National Univ.", "source_org_type": "大学", "row_number": 527, "target_meta": "PIN1", "MOA_meta": "其他"}, {"drug_name": "pHLIP-PNA-antimiR-888", "company": "Old Dominion University", "org_type": "大学", "target": "miR-888", "modality": "ASO", "importance_level": "低", "total_score": 42.5, "institution_score": 25, "track_score": 65, "milestone_score": 45, "field_heat_score": 55, "bonus_score": 2, "brief_reason": "药物通过pHLIP递送PNA抗miR-888/ASO抑制促癌miR-888，针对晚期前列腺癌；大学机构分数较低，处于早期动物模型验证阶段，整体赛道有一定小核酸+肿瘤酸性环境靶向递送创新性，但开发阶段和机构影响力限制重要性。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/2341", "id": "HVXM_5wBX1NQZOEH-LO6", "source_drug_name": "pHLIP-PNA-antimiR-888", "title": "Developing the miR-888 cluster members as an antimiRNA therapy for aggressive prostate cancer", "abstract_text": "Metastatic prostate cancer (PCa) represents an unmet treatment need, with a 5-year survival rate of only 30%. MicroRNAs (miRNAs) are small noncoding RNAs that hold therapeutic promise for PCa and act as important tumor suppressors and pro-oncogenic factors in the prostate. The Kerscher lab identified the miR-888 cluster as preferentially enriched in human metastatic PCa cell lines and prostatic fluids from patients with high-grade PCa compared to low-grade or non-cancer patients. We showed that cluster members promoted prostate growth and aggressiveness in vitro, particularly miR-888 and miR-891a, and these miRNAs accelerated tumor load in mice. Reciprocally, inactivation of miR-888 and miR-891a using antisense oligos reversed these effects, highlighting their potential as antimiR targets for PCa. AntimiRs are valuable tools for inhibiting miRNA function, but current antimiR therapies require high dosage and suffer from poor tissue specificity. To address these shortcomings, the Kerscher lab collaborated with Dr. Raman Bahal’s group to test the efficacy of their acid-sensing peptide pHLIP (pH low insertion peptide) as a novel prostate tumor delivery reagent conjugated to peptide nucleic acids (PNAs) designed to inhibit miR-888 or miR-891a. We hypothesized that pHLIP-PNA-antimiRs against miR-888/-891a would allow efficient delivery to prostate tumors (with inherently acidic microenvironments) and inhibit progression to lethal disease. We also predicted more pronounced effects in castration-resistant PCa. Indeed, when endogenous miR-888/891a levels were analyzed by qRT-PCR across a panel of human PCa cell lines representing the spectrum of this disease, we noted that miR-888 & miR-891a expression was especially elevated in castration-resistant, neuroendocrine PCa lines. pHLIP-PNA-antimiR-888 and antimiR-891a reagents were further validated in vitro to reduce miRNA levels and suppress cancer phenotypes in PCa cell lines. For these experiments, PCa cells were treated with 4 uM pHLIP-PNA-antimiR or control reagents in pH 6.0 media for 3 hours, recovered for 24-48 hours, and harvested for qRT-PCR, WST-1 (proliferation), and soft agar (anchorage-independent growth) assays. As predicted, pHLIP-PNA-antimiR treatment reduced growth more effectively in metastatic PC3-ML than in indolent LNCaP cells. Ultimately, we sought to determine pHLIP-PNA-antimiR efficacy in a xenograft mouse model. We first validated that cy5-pHLIP alone efficiently targeted PC3-ML xenografts in mice, with low signal in kidney and liver. In a pilot efficacy study, we then injected PC3-ML cells into the flanks of mice. When tumor volume reached ~300 mm³, animals were injected with pHLIP-PNA-antimiR-891a or -NC67 controls by tail vein on days 1, 4, 8, and 11. This preliminary study showed that antimiR-891a reduced tumor load. These novel pHLIP-PNA-antimiR reagents demonstrate clinical promise for late-stage PCa.", "source_company": "Old Dominion University", "source_org_type": "大学", "row_number": 670, "target_meta": "not available", "MOA_meta": "反义疗法"}, {"drug_name": "anti-PD-1", "company": "Yonsei University College of Medicine", "org_type": "大学", "target": "PD-1", "modality": "inhibitor", "importance_level": "低", "total_score": 42.5, "institution_score": 25, "track_score": 75, "milestone_score": 30, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "anti-PD-1为已上市免疫检查点抑制剂，靶向PD-1，但摘要聚焦NRAS突变黑色素瘤的内在免疫应答缺陷机制研究，非药物开发项目。大学机构+基础研究性质导致整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5701", "id": "RFXM_5wBX1NQZOEH-LO6", "source_drug_name": "anti-PD-1", "title": "Intrinsic failure of immune activation in NRAS-mutant melanoma reveals a targetable mechanism of checkpoint resistance", "abstract_text": "Background: Melanoma is frequently driven by MAPK pathway mutations, most prominently BRAF (~50%) and NRAS (20-30%). Unlike BRAF-mutant melanoma, which benefits from effective targeted therapies, NRAS-mutant melanoma responds poorly to MEK inhibition and lacks approved targeted options, contributing to poorer outcomes. This limitation has encouraged immunotherapy-based combinations, yet responses to immune checkpoint blockade (ICB) remain variable. We found that NRAS-mutant melanoma exhibits high immune-gene activity in cancer cells alone but shows suppressed inducibility upon immune stimulation, indicating an intrinsic failure to activate immune programs that may limit ICB responsiveness.\nMethods: DEG and pathway analyses were performed using DESeq2 and GSEA with TCGA-SKCM (tumor biopsy) and CCLE/DepMap (cell line RNA-seq) datasets. “Shift genes” were defined by comparing relative expression between cell line-intrinsic and tumor datasets, selecting genes with the largest directional changes and significant adjusted p-values (FDR < 0.05, moderated t-tests). Anti-PD-1-resistant cell lines were generated through serial in vivo selection involving repeated implantation and anti-PD-1 treatment of NRAS-mutant melanoma until tumor growth matched untreated controls.\nResults: RNA expression analysis of NRAS-mutant melanoma cell lines revealed strong intrinsic immune-gene activity; however, this activity was markedly reduced in TCGA tumors, indicating suppressed inducibility in the tumor setting. Among the T cell-inflamed GEP genes—an established immune signature highly expressed in tumors responding to anti-PD-1 therapy—MHC class II-related genes and CCL5 showed the most pronounced reduction (≈1.3-1.4-fold), while most others remained stable. Consistent with these findings, NRAS-mutant murine melanoma cell lines exhibited high basal immune-gene expression but nearly 200-fold weaker induction following Interferon-γ stimulation—used to evaluate inducible immune-gene responses—compared with wild-type cells. Anti-PD-1-resistant models mirrored this pattern, suggesting that such immune non-responsiveness reflects an inherent characteristic of NRAS-mutant melanoma.\nConclusion: The immunotherapy responsiveness of NRAS-mutant melanoma remains uncertain, underscoring the need to define its immune features. Our findings indicate that the immune unresponsiveness in this subtype reflects a fundamental, cell-intrinsic limitation rather than an acquired consequence, suggesting a targetable mechanism to improve ICB outcomes.", "source_company": "Yonsei University College of Medicine", "source_org_type": "大学", "row_number": 699, "target_meta": "PD1", "MOA_meta": "抑制剂"}, {"drug_name": "anti-PD-1 antibody", "company": "Affiliated Sanming First Hospital of Fujian Medical University", "org_type": "医院", "target": "PD-1", "modality": "inhibitor", "importance_level": "低", "total_score": 42.5, "institution_score": 25, "track_score": 75, "milestone_score": 35, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "药物为已知anti-PD-1抗体，靶点PD-1；联合温和热疗增强疗效的研究来自地方医院，处于概念验证阶段，无新药或新机制亮点。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5174", "id": "K1XM_5wBX1NQZOEH-LS6", "source_drug_name": "anti-PD-1 antibody", "title": "Thermal trapping of MMC7 induces G2/M arrest, autophagy, and cGAS-STING signaling to augment anti-PD-1 efficacy", "abstract_text": "Background: Overcoming resistance to immune checkpoint blockade, such as anti-PD-1 therapy, remains a critical challenge in oncology. This study investigates the potential of mild hyperthermia to modulate tumor cell biology and enhance immunotherapy efficacy.\nMethods: Human tumor cell lines were subjected to mild hyperthermia (42°C) for 4 hours. Chromatin binding of MMC7 was assessed by chromatin fractionation and immunofluorescence. Cell cycle distribution was analyzed by flow cytometry. Autophagy induction was evaluated using LC3B-II conversion and autophagosome formation assays. Activation of the cGAS-STING pathway was measured via phosphorylation of STING and TBK1, and interferon-stimulated gene (ISG) expression. In vivo efficacy was validated using syngeneic mouse tumor models treated with hyperthermia (localized 42°C for 4 hours) combined with anti-PD-1 antibody.\nResults: Sustained mild hyperthermia (42°C for 4 hours) specifically inhibited the dissociation of MMC7 from chromosomes, resulting in prolonged G2/M phase arrest in tumor cells. This arrest triggered significant induction of autophagy and robust activation of the cGAS-STING innate immune signaling pathway, characterized by increased cGAS activity, STING/TBK1 phosphorylation, and downstream ISG expression. Critically, this hyperthermia-induced immunogenic state synergistically enhanced the anti-tumor efficacy of PD-1 blockade therapy. Mouse tumor models recapitulated these findings, demonstrating significantly improved tumor control and survival in cohorts receiving the combination of localized hyperthermia and anti-PD-1 compared to either treatment alone.\nConclusion: Our findings demonstrate that controlled mild hyperthermia (42°C, 4h) induces persistent MMC7-chromatin binding, leading to G2/M arrest, autophagic activation, and potent stimulation of the cGAS-STING pathway within tumor cells. This creates a favorable tumor microenvironment that overcomes resistance and synergistically enhances the effectiveness of PD-1 checkpoint blockade immunotherapy. This combination strategy presents a promising novel approach for improving cancer treatment outcomes.", "source_company": "Affiliated Sanming First Hospital of Fujian Medical University", "source_org_type": "医院", "row_number": 861, "target_meta": "PD1", "MOA_meta": "抑制剂"}, {"drug_name": "KHN705", "company": "Sichuan Honghe Biotechnology Co., Ltd.", "org_type": "公司", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 42, "institution_score": 45, "track_score": 50, "milestone_score": 30, "field_heat_score": 40, "bonus_score": 0, "brief_reason": "KHN705为生物合成来源的广谱抗肿瘤分子，但摘要仍处于embargo状态，未披露具体靶点、机制或modality信息。机构为国内中小型biotech，开发阶段和亮点不明，导致整体评分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11308", "id": "QFXM_5wBX1NQZOEH-LO6", "source_drug_name": "KHN705", "title": "Broad-spectrum antitumor activity of the biosynthetically derived molecule KHN705", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Sichuan Honghe Biotechnology Co., Ltd.", "source_org_type": "公司", "row_number": 235, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "CDK4/6 inhibitors", "company": "Oslo University Hospital", "org_type": "医院", "target": "CDK4/6", "modality": "inhibitor", "importance_level": "低", "total_score": 42, "institution_score": 30, "track_score": 80, "milestone_score": 20, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "该记录针对CDK4/6抑制剂联合内分泌治疗在HR+/HER2-乳腺癌新辅助中的精准生物标志物外部验证，靶点为CDK4/6，但摘要仍处于禁运状态，无新药或具体机制披露。机构为医院/学术类型得分较低，赛道虽热门但本条仅为验证性研究无里程碑进展，总分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11333", "id": "VlXM_5wBX1NQZOEH-LK6", "source_drug_name": "CDK4/6 inhibitors", "title": "Precision biomarkers for cdk4/6 inhibitors plus endocrine treatment inHR+/HER2-breast cancer: External validation of mechanistic and hybrid predictive models across multiple neoadjuvant trials.", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Oslo University Hospital", "source_org_type": "医院", "row_number": 541, "target_meta": "CDK4,CDK6", "MOA_meta": "抑制剂"}, {"drug_name": "phenylacetaldehyde", "company": "The Ohio State University College of Medicine", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 42, "institution_score": 35, "track_score": 45, "milestone_score": 45, "field_heat_score": 50, "bonus_score": 2, "brief_reason": "phenylacetaldehyde为肠道菌群代谢物，通过诱导ER stress、自噬及ROS耗竭抑制CRC，无明确药物靶点。大学机构+早期机制研究+组合5-FU增效，整体开发价值和热度较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6773", "id": "clXM_5wBX1NQZOEH-LS6", "source_drug_name": "phenylacetaldehyde", "title": "Phenylacetaldehyde induces apoptosis through endoplasmic reticulum stress and potentiates the effect of 5-FU treatment in colorectal cancer", "abstract_text": "Introduction: Phenylacetaldehyde (PAA), a product of phenylalanine metabolism, is generated by microbiota and has demonstrated anticancer properties in breast cancer. As intestinal homeostasis is influenced by the gut microbiome, we investigated the effect of PAA on colorectal cancer (CRC).\nMethods: Serum PAA levels and feces microbiota from a test cohort of 30 CRC patients and 30 healthy control patients were analyzed by targeted GC-MS/MS and metagenomic sequencing. A validation cohort of 75 CRC patients and 53 healthy control patients was analyzed for PAA levels in serum. CRC cell lines and CRC-patient-derived organoids were cultured and treated with PAA alone or in combination with 5-fluorouracil (5-FU), then evaluated for viability, proliferation, , and cell death in vitro. The effect of PAA alone or in combination with 5-FU on tumor growth was also tested in vivo. We identified the mechanisms induced by PAA treatment using RNA sequencing, western blot, immunostaining, ROS quantification assay, cysteine and glutathione quantification.\nResults: PAA levels were significantly decreased in the circulation of CRC patients compared to healthy controls in our study population and the validation cohort. Metagenomic sequencing indicated the bacteria that positively correlated with PAA levels were significantly more abundant in healthy controls; while bacteria that negatively correlated with PAA were more abundant in CRC. In vitro, PAA inhibited the viability and colony formation of CRC cell lines as well as human-derived organoids in a concentration-dependent manner. Mechanistically, PAA treatment induced generation of ROS leading to cysteine and reduced glutathione depletion. An investigation by RNA sequencing and immunoblotting showed that PAA inhibits CRC by inducing endoplasmic reticulum stress-induced autophagy accompanied by downregulation in PI3K/AKT/mTOR and ERK pathways. When combined with 5-FU, PAA enhanced the potency of 5-FU on viability, cell death, DNA damage and tumor growth.\nConclusions: The bacteria metabolite PAA increased CRC cell death by endoplasmic reticulum stress-induced autophagy and downregulation of the PI3K/AKT/mTOR and ERK pathways. PAA also potentiated the chemotherapeutic efficacy of 5-FU through induction of DNA damages. These findings warrant further exploration of PAA as a potential CRC biomarker and novel therapeutic agent.", "source_company": "The Ohio State University College of Medicine", "source_org_type": "大学", "row_number": 912, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "OG-L002", "company": "Nationwide Children's Hospital", "org_type": "医院", "target": "LSD1", "modality": "inhibitor", "importance_level": "低", "total_score": 42, "institution_score": 30, "track_score": 60, "milestone_score": 40, "field_heat_score": 50, "bonus_score": 0, "brief_reason": "OG-L002为不可逆LSD1抑制剂，在EwS中用于探讨LSD1的非酶促功能，但摘要显示其表型细胞系依赖且酶活性在部分细胞系中非必需。机构为医院研究性质、处于工具化合物/机制探索阶段、非热门临床赛道导致总体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3801", "id": "tZ7M_5wBZznHJdnt_W3O", "source_drug_name": "OG-L002", "title": "LSD1 performs demethylase-independent and context-specific functions in Ewing sarcoma", "abstract_text": "Ewing sarcoma (EwS) is an aggressive malignancy afflicting adolescents and young adults. A chromosomal translocation fusing the EWSR1 gene to the FLI1 gene (EWSR1::FLI1) causes 85% of cases. Due to the inability to target EWSR1::FLI1, the field has attempted to target critical co-regulators to disrupt oncogenesis. One candidate is Lysine specific demethylase 1 (LSD1), which is overexpressed in EwS, colocalizes with the fusion, and inversely correlates with patient prognosis. LSD1 inhibitors have shown mixed activity in EwS. Noncompetitive LSD1 inhibitors have potent cytotoxic activity, but these effects are not seen with irreversible inhibitors. Recent work from our group suggests the activity of noncompetitive inhibitors is likely LSD1-indpendent. This has left the precise function of LSD1 in EwS unclear. We hypothesize that LSD1 has important nonenzymatic functions in EwS. We have developed a suite of genetic and pharmacological tools to deplete LSD1 and define its nonenzymatic functions. Genetically, we knocked out LSD1 via CRISPR genome editing. Pharmacologically, we degraded full-length LSD1 protein with UM171. We assessed proliferation and transformation capacity and identified differentially expressed genes with RNA sequencing. To distinguish between enzymatic and nonenzymatic functions, we also used genetic and pharmacological approaches. We engineered a full length, wild type LSD1 (LSD1wt) and a K661Q/A539E mutant enzymatically dead LSD1 (LSD1ed). Pharmacologically, we treated parental cells with irreversible inhibitor OG-L002. RNA-sequencing was used to define genes regulated by enzymatic and nonenzymatic functions. Surprisingly, LSD1 KO does not impair proliferation or anchorage independent growth. In contrast, degradation of LSD1 protein caused a pronounced, cell line-dependent reduction in colony formation. This cell line-specific reduction in colony formation was recapitulated with OG-L002 treatment. Overlap and pathway analysis found that LSD1 has both shared and cell line-specific targets. Across all cell lines, LSD1 consistently represses genes involved in neurotransmitter functioning and e-cadherin targets. In A673 cells, LSD1wt and LSD1ed demonstrated highly overlapping expression profiles. In addition, OG-L002 treatment showed no phenotype, suggesting that LSD1’s enzymatic activity is dispensable for core functions in A673. When we define nonenzymatic functions pharmacologically, we see that LSD1 performs core functions through both enzymatic and nonenzymatic means. Interestingly, repression of e-cadherin target genes is consistently a nonenzymatic function. Our results demonstrate that LSD1 has a core set of functions that it regulates via cell line dependent mechanisms. In addition, the changes seen in 3D assays with LSD1 inhibition and depletion suggest LSD1 plays a more important role in 3D growth and that future studies should prioritize 3D assays.", "source_company": "Nationwide Children's Hospital", "source_org_type": "医院", "row_number": 1078, "target_meta": "LSD1", "MOA_meta": "抑制剂"}, {"drug_name": "anti-PD1", "company": "Fuzhou University Affiliated Provincial Hospital", "org_type": "医院", "target": "PD-1", "modality": "inhibitor", "importance_level": "低", "total_score": 41.5, "institution_score": 20, "track_score": 75, "milestone_score": 40, "field_heat_score": 65, "bonus_score": 2, "brief_reason": "anti-PD1为PD-1抑制剂，属于免疫检查点热门靶点，但仅作为联合用药出现在糖尿病相关胰腺癌的机制研究中，无独立药物开发信息。机构为医院附属，preclinical组合策略阶段，整体开发价值和里程碑强度有限。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4932", "id": "aVXM_5wBX1NQZOEH-LK6", "source_drug_name": "anti-PD1", "title": "SRSF1 orchestrates splicing-directed dual-engine glucose metabolism driving chemoresistance in diabetes-associated pancreatic cancer", "abstract_text": "Background: Pancreatic ductal adenocarcinoma (PDAC) patients with concurrent type 2 diabetes mellitus (T2DM) exhibit significantly worse treatment responses and shorter survival rates. However, the molecular mechanisms underlying diabetes-driven chemoresistance and immune suppression remain poorly understood. This study aims to elucidate how the diabetic microenvironment promotes PDAC chemoresistance through the splicing-metabolism axis.\nMethods: We investigated SRSF1-mediated splicing regulation using clinical samples from 28 advanced PDAC patients receiving AG chemotherapy, T2DM-associated PDAC mouse models (KPC, KPSC), patient-derived organoids, and multiple in vivo models. Mechanistic studies included scRNA-seq, eCLIP-seq, ATAC-seq, RIP, ChIP-qPCR, and metabolic flux analysis.\nResults: This study revealed that pancreatic cancer with concurrent diabetes is prone to chemoresistance, accompanied by SRSF1-driven elevated back-splicing ratios and altered pyruvate metabolism. Mechanistic investigation found that lactate accumulation in the diabetic microenvironment induced K48 lactylation of SRSF1 protein, enhancing its stability and promoting back-splicing events. SRSF1 regulated the linear-to-back splicing conversion of PSMA3-AS1 to circ-PSMA3-AS1, ultimately promoting transcriptional upregulation of metabolic enzymes DLAT and LDHA. DLAT/LDHA provided metabolic resilience through enhanced mitochondrial fusion and glycolysis, enabling cells to activate both TCA cycle and glycolytic energy-producing systems to acquire chemoresistance. Additionally, this metabolic remodeling profoundly impacted the tumor immune microenvironment through upregulated PD-L1 and sustained lactate production, causing immune evasion, suppressing CD8+ T cell function, and promoting Treg expansion. This process constituted a self-reinforcing positive feedback loop, resulting in the intractability of diabetes-associated pancreatic cancer. Based on these mechanistic discoveries, we developed a triple combination therapy (Berberine + anti-PD1 + AG) targeting SRSF1, DLAT, and LDHA while reducing glucose and tumor lactate levels, significantly improving treatment efficacy in diabetic PDAC models.\nConclusions: This study reveals the mechanistic framework underlying poor outcomes in diabetes-associated PDAC and provides a clinically translatable therapeutic strategy. The discovery of the splicing-metabolism-immunity axis opens new avenues for targeting metabolic vulnerabilities in cancer treatment, with particular significance for the growing population of diabetic cancer patients.", "source_company": "Fuzhou University Affiliated Provincial Hospital", "source_org_type": "医院", "row_number": 37, "target_meta": "PD1", "MOA_meta": "抑制剂"}, {"drug_name": "CTLA-4 inhibitors", "company": "UT MD Anderson Cancer Center", "org_type": "医院", "target": "CTLA-4", "modality": "inhibitor", "importance_level": "低", "total_score": 41.5, "institution_score": 35, "track_score": 75, "milestone_score": 20, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "CTLA-4抑制剂为经典免疫检查点靶点，赛道成熟且仍有热度，但研究由医院/学术机构开展，仅为基础机制探索，无药物开发里程碑，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9533", "id": "EVXM_5wBX1NQZOEH-LO6", "source_drug_name": "CTLA-4 inhibitors", "title": "Integration of spatial single cell proteomics and spatial metabolomics reveals tumor microenvironment predictive of immunotherapy response in mucosal melanoma", "abstract_text": "Background: Mucosal melanoma (MuM) is a rare melanoma subtype, accounting for only 1-2% of all melanoma cases, yet is highly aggressive, demonstrating poorer responsiveness to immune checkpoint blockade than the more common cutaneous melanoma. However, the biological mechanisms driving therapeutic resistance in MuM remain poorly understood. This study aims to uncover spatial and molecular mechanisms underlying response and resistance of MuM to immune checkpoint blockade therapies.\nStudy Design and Methods: An integrative spatial multi-omics framework was applied, which combined single-cell spatial proteomics using COMET platform with high mass resolution spatial metabolomics using imaging mass spectrometry (MALDI-IMS). We comprehensively profiled cellular compositions and spatially defined cellular neighborhoods (CNs) across 97 FFPE tissue cores from 26 MuM patients treated with PD-1/PD-L1 or CTLA-4 inhibitors. Spatial organization, cell-cell interactions, proteomic profiles and metabolomic features of CNs were further compared across responders and non-responders.\nResults: The comprehensive approach enabled spatially resolved profiling of 695,444 single cells, which were categorized into 25 cellular phenotypes spanning 9 major cell lineages. Spatial cellar neighborhood analysis revealed 15 biologically distinct CNs that differed in their composition and spatial distribution of tumor, immune, and stromal cell compartments. In patients who responded to immunotherapy, three tumor-associated CNs—the central tumor, invasive tumor, and tumor boundary CNs—were significantly enriched and collectively formed unique spatial organization patterns. Notably, the invasive tumor CN and tumor boundary CN were characterized by spatial proximity among Ki67⁺ tumor cells, CD163⁺ macrophages, and CD11c⁺ dendritic cells. These CD163⁺ macrophages exhibited reduced expression of IRF4 and Arg1, consistent with lower immunosuppressive activity. Conversely, non-responders exhibited a stromal-dominant CN composed primarily of SMA- stromal cells and demonstrated reduced immune infiltration in both pre-treatment and post-treatment samples. Spatial metabolomic profiling further revealed a pronounced reduction of tryptophan-derived indole metabolites in responders, which significantly correlated with CD11c and CD163 expression, indicating coordinated immunometabolic remodeling within the tumor microenvironment.\nConclusions: These findings highlight that spatial tumor-immune architecture, stromal exclusion, and metabolic rewiring collectively shape immunotherapy response in MuM. The identified spatially resolved tryptophan-derived metabolite signatures offer promising biomarkers and potential therapeutic targets to improve treatment outcomes in this clinically challenging melanoma subtype.", "source_company": "UT MD Anderson Cancer Center", "source_org_type": "医院", "row_number": 50, "target_meta": "CTLA4", "MOA_meta": "抑制剂"}, {"drug_name": "BRACO-19", "company": "Frederick National Laboratory for Cancer Research", "org_type": "研究机构", "target": "G-quadruplex", "modality": "other", "importance_level": "低", "total_score": 41.5, "institution_score": 35, "track_score": 65, "milestone_score": 30, "field_heat_score": 50, "bonus_score": 0, "brief_reason": "BRACO-19为G-quadruplex配体，主要靶向端粒G4结构以抑制端粒酶和干扰基因组稳定，但摘要中单药活性有限，仅作为对照工具化合物用于组合筛选。由联邦研究机构开展的preclinical 3D模型研究，无明显临床推进里程碑，整体开发热度和机构影响力较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4030", "id": "mlXM_5wBX1NQZOEH-LO6", "source_drug_name": "BRACO-19", "title": "Combinatorial profiling of pidnarulex and other G-quadruplex ligands in 3D multicellular tumor spheroids", "abstract_text": "G-quadruplexes (G4s) are four-stranded nucleic acid structures that help regulate key cellular processes and are attractive therapeutic targets in oncology. To assess the therapeutic potential of three G4 ligands—pidnarulex, APTO-253, and BRACO-19—we performed a high-throughput drug-combination screen across thirty-one multicellular tumor spheroids derived from patient tumors and established cancer cell lines. These 3D spheroids model salient features of the tumor microenvironment, incorporating malignant, endothelial, and mesenchymal components. Combination partners were selected for mechanistic relevance to G4 biology, including inhibitors of DNA damage response (DDR), replication stress, and chromatin regulation, based on the proposed roles of G4s in replication and genome stability. Responses were quantified using viability assays complemented by longitudinal brightfield imaging to track spheroid morphology and growth. Drug interactions were evaluated by Bliss independence and volume under the viability surface, providing complementary metrics of synergy and global response. Among the ligands, pidnarulex showed the broadest single-agent activity, whereas APTO-253 and BRACO-19 produced more limited effects. Combination screening with PARP inhibitors, DDR-kinase inhibitors (ATM, ATR, DNA-PK), and cell-cycle regulators (WEE1, PIM1) revealed model-specific synergy. Notably, pidnarulex exhibited consistent synergy in one of eight pancreatic adenocarcinoma models (966289-007-R4-J1) across multiple DDR-targeted combinations. Additional interactions were observed with HDAC inhibitors in a subset of models. Brightfield imaging corroborated enhanced suppression of spheroid growth in synergistic combinations. These data highlight the context-dependent activity of G4 ligands and support integrated functional plus imaging-based approaches to define therapeutic combinations in physiologically relevant 3D cancer models. This project was funded with federal funds from the National Cancer Institute, National Institutes of Health, under Contract No. 75N91019D00024.", "source_company": "Frederick National Laboratory for Cancer Research", "source_org_type": "研究机构", "row_number": 59, "target_meta": "G4", "MOA_meta": "其他"}, {"drug_name": "MUC4-IRDye800CW", "company": "University of California San Diego", "org_type": "大学", "target": "MUC4", "modality": "荧光显像剂", "importance_level": "低", "total_score": 41.5, "institution_score": 35, "track_score": 45, "milestone_score": 45, "field_heat_score": 40, "bonus_score": 0, "brief_reason": "该药为抗MUC4抗体偶联近红外染料IRDye800CW，用于胃癌原发和腹膜转移的荧光显像。大学机构+早期动物模型验证（preclinical成像），赛道非热门治疗而是诊断显像，整体开发热度和里程碑价值较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6259", "id": "31XM_5wBX1NQZOEH-LG6", "source_drug_name": "MUC4-IRDye800CW", "title": "Targeting primary gastric tumors and peritoneal metastases in cell-derived xenograft mouse models using an anti-mucin-4-antibody conjugated near infrared fluorophore", "abstract_text": "Introduction: The purpose of the present study is to validate the use of an anti-MUC4 antibody conjugated near infrared dye to target primary and metastatic gastric cancers in nude mouse models.\nMethods: Subcutaneous models were created in nude mice by injecting 106 cells of human gastric cancer cell lines SNU-16 or NCI-N87 into their flanks. These tumors were excised after 2 months and 1 mm3 fragments were implanted into the stomachs of nude mice to establish orthotopic gastric cancer models of SNU-16 and NCI-N87. Experimental metastasis models were established by injecting 106 SNU-16 or 106 NCI-N87 cells intraperitoneally in nude mice. 2-3 months after tumor implantation mice were injected via tail vein with a mucin4 antibody conjugated to a near infrared fluorescent dye IRDye800CW (MUC4-IRDye800CW). Mice were sacrificed 72 hours after tail vein injection of 50 µg MUC4-IRDye800CW and imaged with the LI-COR Pearl Imaging System and a Stryker laparoscope. The tumor-to-background ratios (TBR) were calculated by dividing the mean fluorescence intensity of the tumors by that of the surrounding stomach. Histopathological analysis was performed on tumors with immunohistochemical (IHC) staining with anti-mucin-4 and anti-immunoglobulin G (IgG) as a negative control.\nResults: 20 total mice were imaged, including 14 primary gastric cancer models and 4 intraperitoneal metastatic gastric cancer models. Primary gastric SNU-16 tumors (n = 6) had a mean TBR of 1.99 (SE ± 0.58), and primary gastric NCI-N87 tumors (n = 8) had a mean TBR of 2.81 (SE ± 1.04). Metastatic SNU-16 tumors (n = 3) had a mean TBR of 3.7 (SE ± 0.75), and metastatic NCI-N87 tumors (n = 3) had a mean TBR of 3.91 (SE ± 0.98). Tumor borders were clearly visualized with both Pearl and the Stryker laparoscope fluorescence imaging systems. Representative tumors stained with anti-mucin-4 stained brown while those stained with anti-IgG did not.\nConclusions: Anti-MUC4-IRDye800CW can be used to accurately localize both primary and metastatic gastric cancer models in nude mice with fluorescence imaging and is promising for identifying both primary tumor margins and intraperitoneal metastasis intra-operatively.", "source_company": "University of California San Diego", "source_org_type": "大学", "row_number": 204, "target_meta": "MUC4", "MOA_meta": "荧光显像剂"}, {"drug_name": "novel non saccharide glycosaminoglycan mimetic", "company": "Virginia Commonwealth University", "org_type": "大学", "target": "key tyrosine kinase receptors", "modality": "other", "importance_level": "低", "total_score": 41.5, "institution_score": 35, "track_score": 65, "milestone_score": 30, "field_heat_score": 50, "bonus_score": 0, "brief_reason": "该分子为非糖胺聚糖模拟物，通过选择性靶向关键酪氨酸激酶受体抑制结直肠癌干细胞，但靶点未明确具体受体。大学机构研发、摘要仍处于embargo阶段、仅preclinical概念水平，整体开发热度和里程碑价值较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11474", "id": "XlXM_5wBX1NQZOEH-LG5", "source_drug_name": "novel non saccharide glycosaminoglycan mimetic", "title": "Novel non saccharide glycosaminoglycan mimetic inhibit colorectal cancer stem cells by selectively targeting key tyrosine kinase receptors.", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Virginia Commonwealth University", "source_org_type": "大学", "row_number": 378, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "Didox", "company": "University of the Pacific", "org_type": "大学", "target": "RRM2", "modality": "inhibitor", "importance_level": "低", "total_score": 41.5, "institution_score": 25, "track_score": 65, "milestone_score": 35, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "Didox为RRM2抑制剂，可增强PARPi在TNBC中的敏感性并逆转耐药，但仅为大学体外细胞系研究，缺乏体内数据和新机制亮点。机构为大学非产业化主体、开发阶段早期导致整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4905", "id": "OVXM_5wBX1NQZOEH-LK6", "source_drug_name": "Didox", "title": "Targeting RRM2 to enhance PARP inhibitor sensitivity in TNBC", "abstract_text": "Triple-negative breast cancer (TNBC) remains one of the most aggressive and therapeutically refractory breast cancer subtypes, primarily due to the absence of hormone receptors and HER2 expression. Poly ADP-ribose polymerase (PARP) inhibitors such as olaparib have demonstrated substantial efficacy in BRCA1/2-mutated TNBC by exploiting synthetic lethality in tumors with defective homologous recombination repair. However, the emergence of acquired resistance to olaparib significantly limits its long-term clinical utility. Ribonucleotide reductase (RR), the rate-limiting enzyme responsible for converting ribonucleotides to deoxyribonucleotides, plays a pivotal role in DNA synthesis and cell-cycle progression. Didox (3,4-dihydroxybenzohydroxamic acid) is a ribonucleotide reductase inhibitor with additional iron-chelating and free-radical scavenging activities. Our previous work identified that the RRM2 subunit is upregulated in TNBC cells and contributes to the development of chemoresistance. The present study investigates whether pharmacologic inhibition of RRM2 using Didox can potentiate olaparib activity and mitigate PARP inhibitor resistance in TNBC models. Four TNBC cell lines—MDA-MB-231, MDA-MB-468, MDA-MB-436, and HCC1937—were utilized to encompass both BRCA-wild-type and BRCA-mutant backgrounds. Cytotoxic responses to olaparib and Didox were quantified by MTS-based IC₅₀ determination, followed by combination index (CI) analysis using the Chou-Talalay method to assess potential drug synergy. Our data show that MDA-MB-436 (BRCA1-mutant) cells were highly sensitive to olaparib, whereas MDA-MB-231 and MDA-MB-468 (BRCA1-wild-type) exhibited marked resistance. Didox displayed moderate single-agent cytotoxicity, however substantially enhanced olaparib sensitivity in resistant lines. Western blot analyses revealed increased DNA damage signaling under combination treatment, indicating that RRM2 inhibition augments PARP inhibitor-induced genotoxic stress. Collectively, these findings support the therapeutic potential of adding an RR inhibitor to overcome PARP inhibitor resistance in TNBC and warrant further in-depth mechanistic and in vivo evaluation.", "source_company": "University of the Pacific", "source_org_type": "大学", "row_number": 521, "target_meta": "RRM2", "MOA_meta": "抑制剂"}, {"drug_name": "SQLE inhibitor", "company": "Shengli Clinical Medical College of Fujian Medical University", "org_type": "大学", "target": "SQLE", "modality": "inhibitor", "importance_level": "低", "total_score": 41.5, "institution_score": 25, "track_score": 60, "milestone_score": 45, "field_heat_score": 50, "bonus_score": 2, "brief_reason": "SQLE抑制剂针对乳酸-组蛋白乳化-SQLE轴，机制新颖可改善老年PDAC免疫抑制微环境，但仅为学术机构大学preclinical水平研究。机构非药企导致institution_score低，开发阶段早期且无临床数据使整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10656", "id": "RVXM_5wBX1NQZOEH-LK6", "source_drug_name": "SQLE inhibitor", "title": "Lactate-driven cholesterol reprogramming induces fibroblast senescence and immune suppression in aged pancreatic cancer", "abstract_text": "Background:Aging profoundly remodels the pancreatic tumor microenvironment (TME), where senescent cancer-associated fibroblasts (senCAFs) accumulate and promote tumor progression. However, the metabolic cues derived from aged tumor cells that induce fibroblast senescence and mediate immune suppression remain poorly understood.\nMethods:Integrated analyses of murine and human single-cell RNA-sequencing datasets combined with multiplex immunofluorescence (mIF) revealed a marked enrichment of p16⁺ senCAFs in aged pancreatic ductal adenocarcinoma (PDAC). Targeted metabolomics and isotope tracing identified lactate as a key metabolite driving fibroblast senescence. Lactyl-proteomics, ATAC-seq, CUT&Tag, and site-directed mutagenesis were used to define functional lactylation sites. Multiplex cytokine profiling identifies the secretome of senCAFs that modulates the immunosuppressive microenvironment.\nResults:Aged PDAC exhibited a marked expansion of senCAFs, validated by scRNA-seq and mIF. Metabolomic and isotope-tracing analyses revealed that lactate secreted by aged tumor cells was preferentially imported by fibroblasts through upregulated MCT1 transporters, triggering metabolic and phenotypic senescence. Proteomic profiling identified enhanced histone A-protein lactylation (H3K18la) as a key senescence-associated modification strongly correlated with poor prognosis. Mutation of the lactylation site (K18R) restored fibroblast proliferative capacity and reduced SASP secretion. Mechanistically, histone lactylation reprogrammed cholesterol metabolism by transcriptionally activating SQLE (squalene epoxidase), a rate-limiting enzyme in cholesterol biosynthesis. Cholesterol accumulation further reinforced fibroblast senescence and sustained inflammatory SASP signaling, including IL-8, CXCL12, and TGF-β, establishing an immunosuppressive tumor microenvironment. Pharmacologic inhibition of SQLE or blockade of lactate import markedly decreased senCAF accumulation, restored CD8⁺ T cell infiltration, and improved survival in aged PDAC models.\nConclusion:Aged PDAC cells metabolically reprogram fibroblasts via lactate-driven histone lactylation, reactivating cholesterol biosynthesis and maintaining senescence. This metabolic-epigenetic axis fuels immune suppression and tumor progression. Targeting the lactate-H3K18la-SQLE pathway offers a promising therapeutic strategy to reprogram the aged tumor stroma and enhance anti-tumor immunity in PDAC.", "source_company": "Shengli Clinical Medical College of Fujian Medical University", "source_org_type": "大学", "row_number": 530, "target_meta": "SQLE", "MOA_meta": "抑制剂"}, {"drug_name": "SERPINB3-binding small molecule", "company": "Washington University School of Medicine in St. Louis", "org_type": "大学", "target": "SERPINB3", "modality": "inhibitor", "importance_level": "低", "total_score": 41.5, "institution_score": 35, "track_score": 45, "milestone_score": 45, "field_heat_score": 50, "bonus_score": 2, "brief_reason": "靶向SERPINB3的小分子通过潜在新机制增强宫颈癌放疗敏感性，目前处于早期preclinical阶段。机构为大学、靶点非热门且机制未完全明确导致总体热度和打分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5671", "id": "9lXM_5wBX1NQZOEH-LK6", "source_drug_name": "SERPINB3-binding small molecule", "title": "Small molecule targeting of SERPINB3 as an anticancer strategy in cervical cancer", "abstract_text": "SERPINB3, also known as squamous cell carcinoma antigen (SCCA) is a cysteine protease inhibitor and prognostic marker associated with poor outcomes in cervical cancer. SERPINB3 blocks lysosomal-mediated cell death by inhibiting lysosomal cysteine proteases such as Cathepsin L and S (CatL, CatS) promoting radioresistance, metastasis, and recurrence. Thus, SERPINB3 is a promising target for translational treatment. We hypothesize that SERPINB3-binding small molecules will sensitize tumor cells to radiation therapy (RT) by disrupting its protease inhibitor activity. Small molecule candidates were identified on a DNA-encoded library screen of 4.4 billion compounds. To test top candidates for cytotoxicity, cervical cancer cell lines CaSki vector control (CTRL) and SERPINB3-overexpressing (B3OE) cells were treated with SERPINB3-targeting small molecules for four hours, followed by increasing doses of RT. Cell death and viability were measured using LDH and CCK8 assays at 48 and 72 hours post-RT, respectively, and significance assessed with ANOVA analyses. Protease activity assays were performed using fluorogenic CatS substrate conversion following preincubation of recombinant SERPINB3 with candidate small molecules. One small molecule enhanced RT-induced cell death in CaSki cells in a concentration-dependent manner. SERPINB3-OE cells displayed even more radiosensitization by this compound compared to CTRL cells. Additionally, no cytotoxic effects were observed in non-malignant END1 cervical epithelial cells. Interestingly, none of the candidate small molecules blocked SERPINB3 function in in vitro protease assays, suggesting an alternative mechanism may be at play. Collectively, these results suggest that small molecule approaches may represent promising therapeutic avenues for targeting SERPINB3 to overcome radioresistance in cervical cancer, and further preclinical development is underway.", "source_company": "Washington University School of Medicine in St. Louis", "source_org_type": "大学", "row_number": 647, "target_meta": "SERPINB3", "MOA_meta": "抑制剂"}, {"drug_name": "statins", "company": "UCLA", "org_type": "大学", "target": "HIF-1α", "modality": "inhibitor", "importance_level": "低", "total_score": 41.5, "institution_score": 30, "track_score": 65, "milestone_score": 35, "field_heat_score": 50, "bonus_score": 2, "brief_reason": "他汀类药物传统靶点为HMGCR，但本研究提出其在侵袭性转移癌中可能通过靶向HIF-1α发挥抗转移作用，而非胆固醇途径。机构为大学非商业研发、处于机制探索的preclinical基础研究阶段、无明确药物开发里程碑，赛道有一定新机制亮点但整体热度和推进有限。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4991", "id": "TFXM_5wBX1NQZOEH-LO6", "source_drug_name": "statins", "title": "Assessing statin sensitivity and hypoxia regulation in aggressive metastatic cancers", "abstract_text": "Statins are a class of small molecule, FDA approved drugs that are widely used to combat cardiovascular disease due to their cholesterol lowering effects. Traditionally, they are competitive inhibitors of HMG-CoA Reductase (HMGCR), a critical enzyme involved in cholesterol synthesis. Previous studies in our lab highlighted that various kinds of statins can effectively kill metastasis-driving clear cell renal cell carcinoma (ccRCC) cells that are von Hippel-Lindau gene (VHL) negative, hypoxia inducible factor (HIF)-1α dominant, while sparing the less aggressive VHL positive, HIF-2α dominant cells. Similar to this metastasis driving ccRCC subpopulation, other aggressive cancers such as triple negative breast cancer (TNBC), and neuroendocrine prostate cancer (NEPC) share the same features of HIF-1α dominance and statin sensitivity. While statins’ cytotoxicity for cancer is well documented, there is still no consensus on their mechanism of action nor is there a rationale explaining why statins are better at killing aggressive cancers. Our findings suggest that HIF-1α could be the target in statin metastasis-blocking mechanism, rather than its known cholesterol-lowering action. This project uses a multi-pronged approach involving qRT-PCR, western blot, and Clustered Regularly Interspaced Short Palindromic Repeats (CRISPR) knockouts to rule out the role of HMGCR and the cholesterol pathway in statin cytotoxicity in all three cancer models (ccRCC, TNBC, and NEPC). By understanding the possible role that the HIF-1α proteins play in mediating statin sensitivity, we aim to further clarify their mechanism of action in aggressive metastatic cancers and make a step forward in developing a new safe and effective drug that can both prevent and treat these cancers.", "source_company": "UCLA", "source_org_type": "大学", "row_number": 705, "target_meta": "HIF-1α", "MOA_meta": "抑制剂"}, {"drug_name": "EMP2-targeted granzyme B fusion", "company": "Texas A&M University Health Science Center", "org_type": "大学", "target": "EMP2", "modality": "other", "importance_level": "低", "total_score": 41.5, "institution_score": 25, "track_score": 65, "milestone_score": 35, "field_heat_score": 50, "bonus_score": 3, "brief_reason": "EMP2靶向的granzyme B融合蛋白通过直接细胞毒和诱导免疫原性细胞死亡（ICD）发挥双重机制。大学机构早期体外研究，缺乏临床进展，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9675", "id": "ZVXM_5wBX1NQZOEH-LS6", "source_drug_name": "EMP2-targeted granzyme B fusion", "title": "Tumor cell targeted granzyme B demonstrates direct cytotoxic action and indirect immunogenic cell death mediated through numerous defined proteins", "abstract_text": "The primary effect of antibody-directed therapeutics is the delivery of cytotoxic payloads directly to antigen-expressing tumor cells resulting in activating cell death mechanisms in the target cells while sparing nonmalignant cells and reducing systemic toxicity. Cytotoxic payloads with the additional capacity to initiate immune activation mechanisms directed against tumor cells as a secondary effect of targeted therapy have the added benefit of initiating “immunogenic cell death” (ICD), which allows further control over residual tumor cells which may be antigen-negative or resistant to the initial cytotoxic effect. Our previous studies in two syngeneic breast cancer mouse models showed that an EMP2-targeted granzyme B fusion significantly enhanced the tumor levels of CD45+ immune cells and tumor-inhibitory M1 macrophages, as well as decreased tumor-supporting M2 macrophages. Tumor cells undergoing ICD express and secrete immunogenic factors such as damage-associated molecular patterns (DAMPs) that are critical in immune cell recruitment and the initiation of immunogenic apoptosis. Accordingly, we investigated whether targeted granzyme B delivery into human tumor cells resulted in the release or expression of DAMP proteins. We tested three human cell lines with varying levels of antigen expression for FOLRa, Fn14, EMP2 and HER2 with scFv-based constructs targeting each of these antigens and delivering the cytotoxic payload granzyme B. In vitro cytotoxicity against each cell line for all four constructs was found to be in the low nanomolar range. Treatment with all four constructs over 72 hours against log-phase tumor cells resulted in the detection of HMGB1 in the conditioned media while detection of released Annexin A1 was restricted to HEY A8 cells targeted via FOLRa. We characterized HMGB1 and Annexin A1 release into the media in a dose dependent (0-100 nM) and time-dependent (4-72h) manner and correlated these events with real-time release of ATP into the conditioned media. Furthermore, we characterized the expression of Calreticulin on the cell surface of each of these cell lines by flow cytometry and investigated the onset of caspase activation by fluorescence imaging. Further studies are ongoing to identify other DAMP-related proteins which may mediate the secondary immunogenic bystander effect against tumor cells. These data support a proposed “dual mechanism” for GrB-based therapeutics which include a direct, antigen-mediated cytotoxic effect and a secondary, immune-mediated effect which can target both antigen-positive and antigen-negative tumors. Research conducted, in whole or in part, by the Clayton Foundation for Research and generously supported by the NCI R21 CA163971.", "source_company": "Texas A&M University Health Science Center", "source_org_type": "大学", "row_number": 901, "target_meta": "EMP2", "MOA_meta": "其他"}, {"drug_name": "MCOPPB", "company": "Palacký University and University Hospital in Olomouc", "org_type": "医院/大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 41.5, "institution_score": 25, "track_score": 65, "milestone_score": 35, "field_heat_score": 50, "bonus_score": 3, "brief_reason": "MCOPPB为NOP受体激动剂，但摘要中发现其意外具有自噬抑制活性，靶点机制为off-target，未明确肿瘤治疗靶点。机构为捷克大学医院，preclinical形态学筛选发现新机制但无明确肿瘤开发里程碑，赛道有自噬调控潜力但整体非热门肿瘤靶向药物。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6488", "id": "alXM_5wBX1NQZOEH-LS6", "source_drug_name": "MCOPPB", "title": "High-content morphology profiling identifies autophagy-modulating compounds and their off-target activities", "abstract_text": "Background: Autophagy gives many tumors a way to cope with stress, adjust their metabolism, and weather therapy. Compounds that interfere with this process, therefore, attract considerable interest. To efficiently spot such compounds, we rely on screening methods that detect subtle shifts in cell structure. The Cell Painting assay offers this possibility: by capturing rich morphological snapshots, it lets us see how different compounds alter organelles and pathways involved in autophagy.\nMethods: We exposed HepG2 cells for 24 hours to several well-characterized autophagy inhibitors—chloroquine, bafilomycin A1, dauricine, daurisoline, and dorsomorphine—as well as two established activators, rapamycin and PP242. MCOPPB and its derivatives MS107 and MS108 were included in the same panels, alongside JUMP-target controls. After staining, we imaged the cells on a Yokogawa CV8000 microscope, recording four channels across nine fields per well. From these images, we extracted and normalized 1,065 single-cell features using pycytominer. Dimensionality reduction (UMAP) and correlation analyses were performed in R, and autophagy markers (LAMP2B, p62/SQSTM1, and LC3) were assessed by immunofluorescence.\nResults: The morphological profiles separated inhibitors from activators with a clear margin, each group forming tight clusters. Inhibitors produced the expected signatures: a fragmented Golgi apparatus, swollen mitochondria, and expanded ER structures, all indicative of impaired autophagic flux. Compounds with known mechanisms behaved as anticipated. Strikingly, MCOPPB—usually classified as a NOP receptor agonist—fell directly into the inhibitor cluster. Follow-up staining corroborated this pattern: disrupted autophagosome-lysosome fusion, p62 accumulation, and LC3 changes all pointed toward autophagy inhibition.\nConclusion: Cell Painting proved effective at distinguishing autophagy-modulating compounds through their characteristic organelle-level effects. The unexpected behaviour of MCOPPB highlights a previously overlooked mechanism. Combining morphological profiling with marker-based validation provides a practical framework for identifying new modulators of autophagy with potential oncological relevance.\nThis work was supported by the Technology Agency of the Czech Republic project PERMED: T2BA (TN02000109). We also acknowledge the contributions from infrastructural projects CZ-OPENSCREEN (LM2023052), EATRIS-CZ (LM2023053), IGA_LF_2025_21, and the SALVAGE project (CZ.02.01.01/00/22_008/0004644) supported by OP JAK, with cofinancing from the EU and the State Budget.", "source_company": "Palacký University and University Hospital in Olomouc\nPalacky University and University Hospital in Olomouc", "source_org_type": "医院\n大学", "row_number": 906, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "anti-Gal-9 antibody", "company": "Hyogo Medical University", "org_type": "大学", "target": "Gal-9", "modality": "antibody", "importance_level": "低", "total_score": 41.5, "institution_score": 25, "track_score": 55, "milestone_score": 45, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "anti-Gal-9 antibody通过阻断Gal-9增强NK细胞对EGFR/ALK驱动NSCLC中DTPs的杀伤，旨在联合TKI实现治愈。大学机构+preclinical水平+Gal-9在免疫治疗赛道中等热度导致总体评分较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1269", "id": "MJ7M_5wBZznHJdnt_W3O", "source_drug_name": "anti-Gal-9 antibody", "title": "Galectin9 targeted therapy for aiming cure in oncogenic driver alterations-positive non-small cell lung cancer", "abstract_text": "Small-molecule tyrosine kinase inhibitors (TKIs) exert dramatic antitumor effect in patients with oncogenic driver alterations-positive non-small cell lung cancer (driver-positive NSCLC). However, it is inevitable for those patients to experience recurrence because of the existence of intrinsic drug-resistant subpopulation called drug-tolerant persisters (DTPs). Therefore, elimination of DTPs is crucial toward complete cure. We examined whether innate immunity could eliminate DTPs for complete cure in driver-positive NSCLC. To identify the key immune checkpoint molecule (ICM) to eradicate DTPs, EGFR mutation-positive NSLC cells (HCC827 and PC-9) and ALK fusion-positive NSLC cells (H3122 and H2228) were exposed to specific TKI osimertinib and alectinib, respectively. Among ICMs, galectin-9 (Gal-9) transcripts were most dramatically upregulated in both driver-positive NSCLC cells via activation of interferon regulatory factor 1 in nucleus. Gal-9 was also overexpressed in both HCC827 osimertinib-resistant cells (HCC827OR) and H3122 alectinib-resistant cells established by continuous exposure to respective TKI. Moreover, TCGA database analysis showed the possibility for Gal-9 to be a negative prognostic factor in lung adenocarcinoma. We next examined whether Gal-9 expression in cancer cells affected the cytotoxicity of natural killer (NK) cells. Cytotoxicity was evaluated by co-incubating cancer cells and NK leukemia cells (NKL) under continuous monitoring using xCELLigence. While exogenous Gal-9 expression weakened NKL-mediated cytotoxicity for HCC827 cells, anti-Gal-9 antibody enhanced the cytotoxicity against HCC827OR cells. We then generated CRISPR/Cas9-mediated Gal-9-knockout (KO) HCC827 cells (HCC827-sgLGALS9) and performed long-term NKL killing assay in the presence of osimertinib for evaluating the cytotoxicity against DTPs. While HCC827-sgLGALS9 cells were completely depleted by osimertinib exposure plus NKL mediated-cytotoxicity, scramble guide RNA-transfected HCC827 cells (HCC827-scr) reproliferated, which suggested that NKL-mediated cytotoxicity failed to eliminate DTPs in HCC827-scr cells. We further engrafted HCC827-scr and HCC827-sgLGALS9 cells into the flank of athymic nude mice and administered osimertinib orally for 30 days. Xenografts in both groups rapidly shrank and disappeared by osimertinib, however, the regrowth rate was higher in HCC827-scr group. Since human Gal-9 has low affinity for mouse immune cells, we transfected mutant human EGFR into NIH 3T3 cells (3T3-EGFRmt) and established allograft model. As expected, osimertinib significantly suppressed the growth of mouse sgLGALS9 transfected 3T3-EGFRmt allografts compared with that of scramble control allografts. Collectively, targeting Gal-9 is promising for aiming cure in driver-positive NSCLC by activating innate immunity against DTPs.", "source_company": "Hyogo Medical University", "source_org_type": "大学", "row_number": 980, "target_meta": "galectin-9", "MOA_meta": "抗体"}, {"drug_name": "RQ-43", "company": "The University of Kansas Medical Center", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 41.5, "institution_score": 25, "track_score": 45, "milestone_score": 55, "field_heat_score": 50, "bonus_score": 0, "brief_reason": "RQ-43为喹啉衍生物，机制涉及下调Snail和β-catenin抑制PDAC细胞EMT、迁移和侵袭，但靶点未明确披露。大学机构+早期动物模型有效但无明确靶点和新机制导致总体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3467", "id": "np7M_5wBZznHJdnt_W3O", "source_drug_name": "RQ-43", "title": "RQ43: A quinoline derivative that inhibits pancreatic cancer cell EMT and migration", "abstract_text": "Background: Pancreatic ductal adenocarcinoma (PDAC) is one of the deadliest cancers due to early metastasis and therapeutic resistance. The epithelial-to-mesenchymal transition (EMT) drives PDAC invasiveness and poor prognosis. RQ-43, a novel quinoline derivative, has shown antiproliferative activity in other cancer models previously with unclear mechanisms. This study investigated its cytotoxic, anti-migratory/invasive effects, and mechanisms of action in PDAC.\nMethods: Human (PANC1) and murine (PAN02) PDAC cell lines were treated with RQ-43 (0.625-20 µM) for 48 h, and cell viability measured by MTT assay. Migration and invasion were assessed using wound-healing and Boyden chamber assays at sub-cytotoxic drug concentrations. EMT-related genes and transcription factors were assessed by qPCR. A syngeneic orthotopic PDAC mouse model was used to assess the in vivo effects of RQ-43 in C57/BL/6 mice.\nResults: RQ-43 selectively decreased PDAC cell viability in a dose-dependent manner with IC₅₀ values of 3.61 µM (PANC1) and 8.24 µM (PAN02). At concentrations of 2.5 µM for PANC1 and 5-20 µM for PAN02, RQ-43 significantly inhibited migration, reducing wound closure by 27.5% in PANC1 and 78% in PAN02 (p < 0.05 compared to controls). Invasion through Matrigel-coated Boyden chamber was also significantly suppressed in both cell lines (p < 0.01). EMT-related transcription factors Snail and B-catenin were downregulated (p < 0.05). In the orthotopic model, RQ-43 treatment (80 mg/kg, daily IP) significantly reduced tumour weight by 62.95% compared with controls. Metastasis rate was 80% in the control group and 25% in the treated group.\nConclusions: RQ-43 demonstrates cytotoxic, anti-migratory/invasive effects in vitro and effectively reduces tumour growth and metastasis in vivo. EMT-related transcription factors were downregulated. Further efficacy and mechanistic evaluation are warranted.", "source_company": "The University of Kansas Medical Center", "source_org_type": "大学", "row_number": 1059, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "BRD9 degraders", "company": "University of Utah Huntsman Cancer Institute / University of Utah", "org_type": "大学/医院", "target": "BRD9", "modality": "degrader", "importance_level": "低", "total_score": 41.5, "institution_score": 35, "track_score": 65, "milestone_score": 30, "field_heat_score": 40, "bonus_score": 0, "brief_reason": "BRD9 degraders靶向BRD9，但摘要明确指出临床试验中多种BRD9 degrader未能取得显著临床缓解，并揭示其机制上反而可能增强GBAF活性导致疗效受限。机构为大学/医院非商业实体、赛道虽为degrader但在SyS中已显临床失败、仅基础机制研究故整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5987", "id": "CZ7M_5wBZznHJdnt_W7O", "source_drug_name": "BRD9 degraders", "title": "BRD9 functions as a negative regulator of GBAF in synovial sarcoma", "abstract_text": "Synovial sarcoma (SyS) incorporates the SS18::SSX fusion oncoprotein into GLTSCR1-containing BRG1/BRM and associated factors (GBAF) complexes, and demonstrated a dependency on GBAF subunit, BRD9. However, SyS clinical trials with multiple BRD9 degraders failed to achieve clinically impactful remissions. Here, we provide a mechanistic framework to explain these results. BRD9 depletion serves to blunt proliferation in SySs harboring minimal genomic alterations, rare in trial participants. In cultured cells, xenografts, and recombinant purified complexes, BRD9 loss does not impact GBAF assembly. Although BRD9 degradation in SyS reduces GBAF enrichment at target loci, BRD9-less complexes maintain or increase chromatin accessibility and associated gene transcription. Biochemical assays with purified recombinant GBAF demonstrate markedly increased nucleosome sliding in the absence of BRD9. Thus, BRD9 restrains GBAF activity, with BRD9 degradation increasing enzymatic remodeling and target gene expression by fusion oncoprotein-distributed GBAFs in SyS. This subtle epigenetic disturbance creates a low hurdle for SyS to surpass.", "source_company": "University of Utah Huntsman Cancer Institute\nUniversity of Utah", "source_org_type": "医院\n大学", "row_number": 1135, "target_meta": "BRD9", "MOA_meta": "降解剂"}, {"drug_name": "Bacillus Calmette-Guérin", "company": "UNIST", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 41, "institution_score": 35, "track_score": 40, "milestone_score": 45, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "BCG为经典免疫治疗药物，本研究未披露新靶点或新modality，仅揭示BCG无应答的生物标志物特征。机构为大学、非头部药企，赛道为已成熟老药机制研究，整体开发价值和创新性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/7811", "id": "iFXM_5wBX1NQZOEH-LO6", "source_drug_name": "Bacillus Calmette-Guérin", "title": "Immune senescence and antigen presentation defects define a pre-existing state of BCG unresponsiveness in bladder cancer", "abstract_text": "Background: Bacillus Calmette-Guérin (BCG) is standard therapy for high-risk non-muscle invasive bladder cancer (NMIBC), yet a substantial proportion of patients fail to respond. Although T-cell dysfunction and impaired antigen presentation have been implicated in BCG resistance, their pre-treatment presence and clinical relevance remain unclear. We aimed to define a reproducible, treatment-specific transcriptomic signature of BCG unresponsiveness centered on antigen presentation machinery (APM) deficiency.\nMethods: We performed single-cell RNA sequencing (scRNA-seq) on 10 pre-treatment NMIBC tumors to identify cellular programs associated with BCG outcomes. Tumor-intrinsic APM activity and interferon pathway status were quantified at the independent bulk transcriptomic cohorts (UROMOL and BRS). Pre-treatment urine samples were assessed for a targeted chemokine panel (IL-6, IL-8, IFN-γ, CXCL10, CXCL13, CCL5, CCL21) to determine concordance between transcriptomic IFN/APM activity and protein-level immune signaling.\nResults: Single-cell profiling revealed that BCG-unresponsive tumors exhibited markedly reduced epithelial APM expression accompanied by suppression of type I/II interferon signaling and loss of plasmacytoid dendritic cell activity. These transcriptomic features were reflected at the protein level: non-responders displayed significantly lower urine chemokine levels prior to BCG instillation. Bulk transcriptomic validation across >350 patients demonstrated that high APM activity robustly predicted improved recurrence-free survival in BCG-treated patients (p < 0.05).\nConclusions: BCG-unresponsive NMIBC is defined by a pre-existing antigen presentation defect coupled with suppressed interferon signaling, detectable at both the transcriptomic and urine protein levels. The APM signature exhibits strong, treatment-specific predictive value across multi-cohort datasets and provides a biologically compelling rationale for APM-restoring or IFN-enhancing intravesical immunotherapies as alternatives for patients unlikely to benefit from BCG.\nAcknowledgments: The results shown here are in part based upon data generated by the TCGA Research Network: https://www.cancer.gov/tcga. We thank the staff of the Department of Urology and Laboratory Medicine at Yonsei University College of Medicine for their technical assistance. We also thank all the patients who participated in this study. This study was supported by grants from the National Research Foundation of Korea (NRF) grants funded by the Korean government (MSIT) (grant numbers: 2022R1A2C2003831). This work was also supported by the National Research Foundation of Korea (NRF) funded by the Ministry of Education (RS-2018-NR031072).", "source_company": "UNIST", "source_org_type": "大学", "row_number": 57, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "MCU inhibitor", "company": "Tianjin Medical Univ. Cancer Inst. & Hospital", "org_type": "医院", "target": "MCU", "modality": "inhibitor", "importance_level": "低", "total_score": 41, "institution_score": 30, "track_score": 60, "milestone_score": 40, "field_heat_score": 50, "bonus_score": 3, "brief_reason": "靶点为线粒体钙单向转运蛋白MCU，机制为抑制PDAC相关癌性恶病质中的NETosis介导骨骼肌萎缩；机构为国内医院/大学类型非头部药企，赛道为小分子抑制剂针对新兴机制但非热门靶点，处于基础研究阶段无明确药物开发里程碑。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8195", "id": "eFXM_5wBX1NQZOEH-LS6", "source_drug_name": "MCU inhibitor", "title": "Mitochondrial calcium uniporter drives cancer cachexia in pancreatic ductal adenocarcinoma through NETosis-mediated skeletal muscle atrophy", "abstract_text": "Purpose: Cancer cachexia, characterized by persistent weight loss, skeletal muscle atrophy, and adipose tissue reduction—with progressive skeletal muscle wasting being the predominant manifestation—represents a major cause of mortality in pancreatic ductal adenocarcinoma (PDAC) patients. Cachexia is a common and severe complication in PDAC, significantly impacting patients' quality of life and prognosis. This study investigates the role of the mitochondrial calcium uniporter (MCU) in PDAC-associated cachexia, potentially offering novel interventional strategies for its prevention.\nExperimental Design: MCU expression was analyzed in PDAC patient tissues and correlated with cachexia incidence. Spontaneous tumor models and orthotopic PDAC models using MCU-overexpressing and control stable cell lines were established to evaluate tumor progression and muscle atrophy. Neutrophil extracellular traps (NETs) formation was detected by H3cit/MPO/DAPI multiplex immunofluorescence. NETs function was examined through anti-Ly6G-mediated neutrophil depletion, DNase I treatment, and Pad4⁻/⁻ mice. Secretome analysis identified MCU-regulated mechanisms in NETs formation, validated through recombinant protein treatment and receptor inhibition. The role of CCDC25 was investigated using genetic knockout models and AAV9-mediated skeletal muscle-specific silencing.\nResults: MCU overexpression significantly correlated with cachexia incidence and reduced skeletal muscle mass in PDAC patients. Compared to the MCU-overexpression group, control mice demonstrated attenuated tumor growth and preserved muscle mass independent of tumor burden. MCU-overexpressing PDAC models showed significantly elevated NETs infiltration in skeletal muscle, while NETs clearance prevented muscle atrophy. MCU overexpression induced cellular senescence and senescence-associated secretory phenotype (SASP) secretion (particularly C3 and CXCL1), promoting NETosis through C3aR and CXCR2 signaling. CCDC25 was identified as a critical NET DNA receptor in skeletal muscle, mediating muscle atrophy through RAC1-dependent ROS production.\nConclusion: Our study reveals a novel signaling pathway wherein tumor MCU overexpression promotes cellular senescence and SASP secretion, driving NETs formation through C3/CXCL1 signaling. NETs engage CCDC25 receptors on muscle cells, activating the RAC1-ROS signaling pathway that ultimately leads to muscle atrophy.\nImpact: These findings establish the MCU-NETs-CCDC25 axis as a key mechanism in PDAC-associated cachexia and suggest multiple therapeutic strategies—including MCU inhibition, NETs degradation, and CCDC25 blockade—providing new directions for alleviating cachexia and preserving muscle mass in cancer patients.", "source_company": "Tianjin Medical Univ. Cancer Inst. & Hospital", "source_org_type": "医院", "row_number": 77, "target_meta": "MCU", "MOA_meta": "抑制剂"}, {"drug_name": "Bifidobacterium adolescentis OP820", "company": "Chonnam National University", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 41, "institution_score": 25, "track_score": 55, "milestone_score": 45, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "OP820为严格厌氧益生菌，通过调控炎症信号和免疫微环境表现出抗结直肠癌作用，但靶点机制未明确披露。大学机构+早期动物模型验证导致整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/7515", "id": "KZ7M_5wBZznHJdnt_W7O", "source_drug_name": "Bifidobacterium adolescentis OP820", "title": "Janus villus chip identifies an anaerobic probiotic that suppresses tumor growth in mice", "abstract_text": "Chronic intestinal inflammation disrupts epithelial integrity and reshapes the tumor immune microenvironment (TIME), accelerating colorectal cancer progression. We investigated how the strict anaerobic mucin-binding probiotic Bifidobacterium adolescentis OP820 modulates inflammation-driven epithelial and immune dysfunction using a Janus oxygen-gradient villus chip and in vivo models. Because Bifidobacterium requires strict anaerobic conditions for viability and physiological activity, the villus chip—engineered with an anaerobic apex and oxygenated base to reproduce the native villus oxygen gradient—was essential for accurately modeling OP820-epithelium interactions. Under these conditions, epithelial cells upregulated MUC13 and MUC17, generating a mucin-rich glycocalyx to which OP820 adhered strongly, reflecting its natural niche preference. Transcriptomic profiling revealed that OP820 modulates inflammatory signaling by elevating CCL8, TGFA, and MMP12—genes linked to epithelial repair and immunoregulatory remodeling—while suppressing TSLP, FLT3LG, and IL18, which are typically associated with heightened inflammatory stress. These coordinated shifts indicate that OP820 promotes a resolution-oriented immune state rather than amplifying inflammation. The effects were consistent across monolayer, spheroid, and villus-chip models, underscoring the robustness of OP820’s immunomodulatory activity under strict anaerobic conditions that reflect its physiological habitat. In vivo, OP820 demonstrated dual therapeutic activity. In the DSS-induced colitis model, it attenuated mucosal injury and preserved epithelial structure, supporting its inflammation-resolving function. In the colorectal cancer xenograft model, intravenous OP820 administration significantly reduced tumor burden, and OP820 cells were detected within the tumor microenvironment, suggesting that intratumoral localization may underlie its immune-modulating and tumor-suppressive activity. The presence of a strict anaerobe within tumors implies the existence of permissive micro-niches and points to direct modulation of local cytokine or stromal networks. Collectively, these findings identify OP820 as a microbiome-derived therapeutic capable of reinforcing epithelial barrier recovery and reprogramming inflammation-driven tumor microenvironments. By integrating villus-chip modeling with in vivo validation, this study highlights OP820’s potential as a mechanism-based intervention for inflammation-associated colorectal cancer.", "source_company": "Chonnam National University", "source_org_type": "大学", "row_number": 278, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "CalRexin:pHrodo Red", "company": "Apop Biosciences Pty Ltd", "org_type": "University of Melbourne", "target": "未披露", "modality": "fluorescent imaging agent", "importance_level": "低", "total_score": 41, "institution_score": 35, "track_score": 45, "milestone_score": 40, "field_heat_score": 50, "bonus_score": 0, "brief_reason": "CalRexin:pHrodo Red为pH敏感荧光探针，用于高通量自噬成像检测，未明确药物靶点，仅为研究工具。大学机构+工具类modality+早期技术开发阶段导致综合重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6805", "id": "K57ECZ0BZznHJdntvNYd", "source_drug_name": "CalRexin:pHrodo Red", "title": "A novel pH-sensitive probe to quantify autophagy on high throughput/content imaging platforms", "abstract_text": "Autophagy is deregulated in various pathological conditions including cardiovascular, neurological, neoplastic, autoimmune and degenerative disorders. However, clinically relevant pharmacological modulators of autophagy remain elusive, calling for the development of novel screening approaches, amenable to high throughput/content applications. Cellular responses were imaged with the novel CalRexinTM:pHrodoTM Red (CalRexinTM, Apop Biosciences Pty Ltd) reagent on the Operetta high content screening platform. Human cervical carcinoma HeLa cells, and mutants RB1CC1-/- (FIP200) and ATG5-/- were induced for autophagy with rapamycin, torin-1 and serum deprivation and inhibited with 3-methyladenine, MRT68921, chloroquine and bafilomycin A1. The co-localisation with pixel definition between CalRexinTM:pHrodoTM Red and markers of early and late endosomes and autolysosomes was studied with high resolution confocal microscopy and Fiji software. Pixel co-localization analysis demonstrated significant overlap between CalRexinTM:pHrodoTM Red and markers of early and late endosomes, as well as LysoTrackerTM, a marker of autolysosomes.CalRexinTM:pHrodoTM Red is accumulated via the endosome-amphisome-autolysosome (low pH ~4.5) pathway, thus connecting to canonical autophagy and yielding a bright fluorescent signal. CalRexinTM:pHrodoTM Red provides a novel approach for imaging autophagy on high throughput/content platforms and is adaptable for screening large chemical libraries for the identification of novel autophagy-modulators as potential drugs for treatment of chronic diseases.", "source_company": "University of Melbourne", "source_org_type": "大学", "row_number": 317, "target_meta": "not available", "MOA_meta": "荧光显像剂"}, {"drug_name": "AEM1", "company": "University of Alabama at Birmingham", "org_type": "大学", "target": "未披露", "modality": "inhibitor", "importance_level": "低", "total_score": 41, "institution_score": 35, "track_score": 40, "milestone_score": 45, "field_heat_score": 50, "bonus_score": 0, "brief_reason": "AEM1为小分子化合物，通过高通量筛选发现可显著诱导胰腺癌细胞表面CALR表达，但靶点机制未明确披露，仅为工具化合物潜力；大学机构+早期筛选阶段+诱导表面CALR的创新应用赛道一般，导致整体评分较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6510", "id": "SlXM_5wBX1NQZOEH-LG5", "source_drug_name": "AEM1", "title": "High throughput screening identifies novel drugs for calreticulin surface translocation in pancreatic ductal adenocarcinoma", "abstract_text": "Background: Pancreatic ductal adenocarcinoma (PDAC) is currently the fourth leading cause of cancer-related deaths in the United States and is projected to increase within the next decade due to its poor prognosis and increasing incidence. There is an urgent need to develop more effective therapeutic options and detection strategies to improve survival outcomes for PDAC patients. Calreticulin (CALR), an endoplasmic reticulum protein, is known to translocate to the cell surface following cellular stress. Surface-expressed CALR holds promise for cancer detection or therapeutic delivery. To explore this potential, we performed high-throughput screening to identify compounds which induce surface CALR expression.\nMethods: Two human PDAC cell lines (Panc1, MIA Pa Ca-2) were engineered using the Nano-Glo HiBiT Extracellular Detection System to stably integrate HiBiT into the CALR gene. A high throughput screen for surface CALR-inducing compounds was performed at the National Center for Advancing Translational Sciences (NCATS). Cell lines expressing HiBiT-CALR were treated with approximately 3,000 drugs from the Mechanism interrogation PlatEs (MIPE) library for 24 or 48 hours and then assessed for cell viability using CellTiter-Glo and surface CALR levels by luminescence. Surface HiBiT-CALR and cell viability signals were quantified using a ViewLux microplate imager and automated processes utilizing the XTS Staubli UniVAL robotic system. The top ten drugs demonstrating high CALR signal (AUC) with minimal toxicity were validated for surface CALR induction by flowcytometry. Cells were also analyzed for viability using MTT assay, with P < 0.05 considered significant.\nResults: Out of the compounds evaluated, 102 compounds showed increased CALR surface expression and were selected for secondary screening, from which ten were further chosen for in-lab validation. Among these, bisindolylmaleimide IV and AEM1 were identified to reliably increase CALR. Flow cytometry analysis confirmed significant increases in live surface CALR+ cells, with bisindolylmaleimide IV (1.1µM) increasing CALR by 1.7-fold in MIA Pa Ca-2 and 1.32-fold in Panc1, while AEM1 (10µM) increased CALR by 7-fold in MIA PaCa-2 and 3.7-fold in PANC-1. Viability assays confirmed low cytotoxicity for bisindolylmaleimide IV (1.1 µM), with 77% and 84% cell viability observed in MIA PaCa-2 and PANC-1 cells, respectively. Similarly, AEM1 (10 µM) showed 81% viability in MIA PaCa-2 and 76% in PANC-1 cells.\nConclusion: Our results identified the potential of two novel drugs, bisindolylmaleimide IV and AEM1, as promising candidates for enhancing surface CALR expression, offering new avenues for PDAC detection and tumor specific delivery of therapies.\nKeywords: Calreticulin, pancreatic ductal adenocarcinoma, drug discovery, therapeutic delivery, HiBiT-CALR.", "source_company": "University of Alabama at Birmingham", "source_org_type": "大学", "row_number": 361, "target_meta": "not available", "MOA_meta": "抑制剂"}, {"drug_name": "Maackia amurensis seed lectin", "company": "Rowan University", "org_type": "大学", "target": "PDPN", "modality": "other", "importance_level": "低", "total_score": 41, "institution_score": 30, "track_score": 40, "milestone_score": 60, "field_heat_score": 50, "bonus_score": 0, "brief_reason": "MASL为植物凝集素，主要靶向PDPN受体上的α2,3-唾液酸残基以抑制OSCC细胞生长和迁移。大学机构、非热门modality、虽有phase 1临床试验数据但整体创新性和开发热度有限导致总分较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/12065", "id": "yFXM_5wBX1NQZOEH-LG6", "source_drug_name": "Maackia amurensis seed lectin", "title": "Effects of Maackia amurensis seed lectin (MASL) on OSCC cell morphology, PDPN expression, viability, and motility in a phase 1 clinical trial", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Rowan University", "source_org_type": "大学", "row_number": 455, "target_meta": "PDPN", "MOA_meta": "其他"}, {"drug_name": "CAV2-AU-M3", "company": "Auburn University", "org_type": "大学", "target": "未披露", "modality": "oncolytic virus", "importance_level": "低", "total_score": 41, "institution_score": 25, "track_score": 65, "milestone_score": 35, "field_heat_score": 45, "bonus_score": 0, "brief_reason": "CAV2-AU-M3为溶瘤病毒载有抗PD-1抗体，用于骨肉瘤的免疫治疗，但靶点未明确披露，仅在体外细胞系验证。大学机构+早期preclinical阶段+溶瘤病毒赛道中等热度导致总体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5586", "id": "MFXM_5wBX1NQZOEH-LK6", "source_drug_name": "CAV2-AU-M3", "title": "Exploring oncolytic viral therapy to target osteosarcoma", "abstract_text": "Osteosarcoma (OS) is a highly aggressive and metastatic bone malignancy that primarily affects children and young adults. Despite advances in multidisciplinary treatment, including surgery, chemotherapy, and radiation therapy, the survival rates for patients with OS have not improved significantly over the past 20 years, especially for those with metastatic disease. We hypothesize that combining cancer immunotherapies will have better therapeutic potential for osteosarcoma. We have successfully combined two immunotherapeutic modalities by developing armed canine conditionally replicative adenoviruses (CAV2-AU-M3). CAV2-AU-M3 is armed with an immune checkpoint inhibitor, an antibody to PD-1 that is released into the tumor microenvironment (TME) upon lysis. We have evaluated the oncolytic activity and production/ secretion of anti-PD1 Ab by CAV2-AU-M3 in four canine OS cell lines, D17-GLP, CF11-GLL, D22-GLP, and MCKOS in 2D and 3D cultures. We have also assayed the production and secretion of anti-PD1 Ab in cell culture media, which binds to the PD1 receptor and plays a role in inhibiting PD1-PDL1 binding. CAV2-AU-M3 represents a next-gen approach to immunotherapies in solid tumors and creates a blueprint to guide the development of similar treatments in solid tumors such as osteosarcoma.", "source_company": "Auburn University", "source_org_type": "大学", "row_number": 516, "target_meta": "not available", "MOA_meta": "溶瘤病毒"}, {"drug_name": "cerberin", "company": "University of Wisconsin-Madison", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 41, "institution_score": 25, "track_score": 45, "milestone_score": 55, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "cerberin为天然产物心脏苷类化合物，机制涉及抑制PI3K/AKT/mTOR信号，未明确自身特定靶点。大学机构+早期筛选协同研究，缺乏临床推进里程碑，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4889", "id": "UVXM_5wBX1NQZOEH-LK6", "source_drug_name": "cerberin", "title": "CRISPR druggable-genome screen identifies BRD4 as a synergistic vulnerability with the natural product cerberin in pancreatic cancer organoids", "abstract_text": "Background: Pancreatic ductal adenocarcinoma (PDAC) acquires resistance to systemic therapy, requiring novel therapeutic combinations. Our prior work demonstrated that cardiac glycosides including cerberin can inhibit PI3K/AKT/mTOR signaling yielding low nanomolar potency in PDAC viability. We recently optimized pooled CRISPR-Cas9 “druggable-genome” screening in 3D PDAC patient-derived organoids (PDOs). Here, we used this platform to define genetic dependencies under cerberin pressure and to nominate synthetic lethal combinations.\nMethods: The KRASG12D-mutant PDO line Pan21 was transduced with a lentiviral CRISPR-Cas9 library targeting 2,312 druggable genes (~10,000 sgRNAs; Millipore-Sigma) using optimized viral particle: cell ratios and 6-day puromycin selection. Baseline samples were collected following. PDOs were expanded using media control and cerberin 10nM for 6 days, followed by 2 days of recovery. Guide representation was assessed by next-generation sequencing, and gene-level dropout was analyzed with MAGeCK robust rank aggregation (RRA). For functional validation, dose-response combination matrices were generated for cerberin or digoxin in combination with the BET inhibitor ZEN-3694 in Pan21 PDOs. Viability was measured at 144h using 3D CellTiter-Glo (CTG, 50% v/v), and synergy was quantified in SynergyFinder 3.0.\nResults: Library QC confirmed stable Cas9 expression, recovery of more than 95% of sgRNAs, and similar log₂ read-count profiles across baseline, control, and cerberin-treated samples. Cerberin treatment generated a consistent dropout pattern enriched for signaling and metabolic regulators; among the highest-ranked negative-selection hits were CYGB, ANXA2, NR1I2, PIK3R1, TWF2, ENPP2, FDX1, PRG2, and the epigenetic reader BRD4. Although this pilot was limited to stringent FDR thresholds, these genes showed low RRA scores at nominal p-values < 0.005. BRD4 was selected among the top 10 depleted genes (RRA score ~6 × 10⁻⁴; nominal p ≈ 0.003) due to availability for synthetic inhibitors from NCI’s Cancer Therapeutics Evaluation Program. In Pan21 PDOs, dose-response combinations of cerberin with ZEN-3694 produced robust synergy (HSA 26.2, Bliss 23.3, ZIP 23.6), with values in a range generally interpreted as strong positive drug-drug interaction and clear synergy “hot spots” at submaximal concentrations of both agents. Similarly, digoxin with ZEN-3694 exhibited a synergistic landscape (HSA 25.3, Bliss 24.7), supporting a cardenolide class effect.\nConclusions: Adopting a CRISPR/Cas9 druggable screen in 3D PDAC PDO models, we provide proof-of-concept for synergy between cardiac glycosides and BRD4/BET inhibitors. This work links a PDO-based CRISPR platform with natural-product pharmacology to provide a framework for mechanistic partners to advance the use of cardiac glycosides for clinical translation.", "source_company": "University of Wisconsin-Madison", "source_org_type": "大学", "row_number": 539, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "COX inhibitor", "company": "Centre Hospitalier Universitaire Vaudois", "org_type": "医院", "target": "COX", "modality": "inhibitor", "importance_level": "低", "total_score": 41, "institution_score": 25, "track_score": 45, "milestone_score": 55, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "摘要中COX抑制剂靶向PGE2-EP2/4通路，在HRD卵巢癌复发前临床模型中联合化疗显著延缓复发并延长生存，显示一定preclinical潜力；但研发机构为医院，整体非药物开发核心主体，赛道非当前最热门，综合重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9488", "id": "SZ7ECZ0BZznHJdntvNYd", "source_drug_name": "COX inhibitor", "title": "Reprogramming T-cell networks to overcome immune evasion in ovarian cancer relapse", "abstract_text": "Ovarian cancer (OC) remains a major clinical challenge due to its high recurrence rates and resistance to standard therapies. High-grade serous ovarian cancer (HGSOC), the most common and aggressive OC subtype, often presents with tumor-infiltrating lymphocytes (TILs), yet immune checkpoint blockade (ICB) therapies have shown limited efficacy. Our studies aim to dissect the spatiotemporal evolution of the OC tumor microenvironment (TME), reprogram T cell networks, and develop next-generation immunotherapies to restore anti-tumor immunity. We integrated high-resolution spatial proteomics, single-cell transcriptomics, and computational modeling to map TIL dynamics across primary, recurrent, and treatment-resistant OC. Preclinical models, including syngeneic BRCA1-mutant and wild-type mouse models of OC recurrence, are employed to investigate tumor-intrinsic and TME-driven mechanisms of immune suppression during OC relapse. We utilized digital pathology multiplex immunofluorescence (mIF) to classify 697 ovarian cancer (OC) specimens from five independent cohorts, offering the most extensive CD8+ T cell-based immune profiling to date. Our predictive algorithm identified distinct tumor immune phenotypes in OC (i.e. purely inflamed, mixed inflamed, excluded, and desert) based on TIL infiltration and spatial organization, which correlate with HRD status and predict therapeutic outcomes. We observed significant immune and molecular heterogeneity between these tumor immune phenotypes and their dynamics during disease recurrence. Inflamed HRD tumors, maintained T cell-myeloid niches post-chemotherapy. In preclinical models, this was associated with restoration of genomic rearrangements. Recurrent murine HRD tumors upregulated the immunosuppressive PGE2-EP2/4 pathway and targeting of COX-driven PGE2 production during chemotherapy significantly prolonged relapse and survival in preclinical mouse models, identifying a key vulnerability for the recurrence of human HRD OCs. In contrast, homologous recombination repair proficient (HRP) OC tumors evolved into T-cell excluded or desert phenotypes, characterized by malignant cells overexpressing Nduf4l2/Galectins and Trem2/ApoE overactive tumor-associated macrophages (TAMs). Our data suggest that therapeutically targeting of TREM2 overexpressing TAMs may improve anti-tumor immune responses and delay recurrence after first-line chemotherapy in HRP OC. By unraveling the cellular and molecular networks driving immune evasion in recurrent OC, our findings provide a roadmap for precision immunotherapy. Our work highlights novel immune biomarkers and therapeutic targets that can be exploited to retune anti-tumor T cell responses, paving the way for clinically actionable strategies in recurrent OC and other immune-resistant malignancies.", "source_company": "Centre Hospitalier Universitaire Vaudois", "source_org_type": "医院", "row_number": 553, "target_meta": "COX", "MOA_meta": "抑制剂"}, {"drug_name": "L19-AuNP", "company": "University of Genoa / Nano Flow", "org_type": "大学", "target": "FN-EDB", "modality": "other", "importance_level": "低", "total_score": 41, "institution_score": 30, "track_score": 65, "milestone_score": 35, "field_heat_score": 50, "bonus_score": 0, "brief_reason": "L19-AuNP为L19抗体修饰的金纳米颗粒，靶向肿瘤微环境中的纤维连接蛋白额外结构域B (FN-EDB)，用于神经母细胞瘤的靶向诊断成像。由大学主导、Nano Flow提供材料，处于初步体外和PDX模型验证阶段，缺乏临床进展和热门赛道特征。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6258", "id": "gFXM_5wBX1NQZOEH-LK6", "source_drug_name": "L19-AuNP", "title": "Fibronectin extra-domain B-recognizing gold nanoparticles as an innovative tool for neuroblastoma targeting", "abstract_text": "Background/Objectives: Neuroblastoma (NB) is the most common extracranial solid tumor in children and accounts for 12-15% of pediatric cancer-related deaths. Current multimodal therapies still lack of specific cellular targets, causing systemic toxicity and drug resistance. The development of innovative tumor-targeted nanoformulations might represent a promising approach to enhance NB diagnosis and antitumor efficacy, while decreasing off targets side effects. Fibronectin extra-domain B (FN-EDB) is upregulated in the tumor microenvironment.\nMethods: Here, FN-EDB expression was evaluated by immunohistochemical (IHC) staining in several animal models of NB. A gold nanoparticle, decorated with an antibody (Ab) recognizing FN-EDB (L19-AuNP) was developed by the company Nano Flow and its tumor binding was tested by ELISA in vitro and in Patient-Derived Xenografts (PDX) models of NB by photoacoustic imaging in vivo.\nResults: All models of NB used expressed FN-EDB, at the tumor cell, stroma and tumor vasculature levels. Compared to the non-targeted (no L19 Ab) Au-NP (size: 35.59 ± 2.54 nm; PDI: 0.47 ± 0.08; zeta potential: -51.18 ± 0.84), L19-AuNP was found to be stable (size: 108.70 ± 1.37 nm; PDI: 0.29 ± 0.07; zeta potential: -28.34 ± 0.48) and able to specifically bind to FN-EDB in vitro. In vivo, L19-AuNP specifically homed into PDX of NB, accumulating more in the tumor expressing higher levels of FN-EDB.\nConclusions: In this preliminary study, L19-AuNP was shown to be a novel diagnostic tool specific for binding NB expressing FN-EDB, paving the way for the development of theranostic nanoformulations co-encapsulating gold moiety and standard-of-care for NB.", "source_company": "University of Genoa", "source_org_type": "大学", "row_number": 569, "target_meta": "EDB-FN", "MOA_meta": "其他"}, {"drug_name": "QNZ", "company": "Aichi Cancer Center Research Institute", "org_type": "研究机构", "target": "未披露", "modality": "inhibitor", "importance_level": "低", "total_score": 41, "institution_score": 35, "track_score": 45, "milestone_score": 40, "field_heat_score": 50, "bonus_score": 0, "brief_reason": "QNZ为报道靶向NF-κB的抑制剂，但实际作用独立于经典NF-κB通路，机制指向GRHL2和Wnt/SOX9相关路径。研究机构背景+早期筛选阶段+机制初步揭示导致整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6122", "id": "DlXM_5wBX1NQZOEH-LO6", "source_drug_name": "QNZ", "title": "Identification of key pathways regulating colorectal cancer stemness and metastasis through compound screening", "abstract_text": "Distant metastasis is the leading cause of mortality in patients with advanced colorectal cancer (CRC), underscoring the need for novel therapeutic targets. Although cancer stem cells are thought to contribute to metastatic progression, the regulatory mechanisms governing CRC stemness remain incompletely understood. Using an autochthonous metastatic mouse model harboring sporadic mutations in Ctnnb1, Kras, Trp53, and Smad4 genes (CKPS mice), together with CRC cell lines derived from these mice (CKPS cells), we previously demonstrated that the cAMP/PKA/CREB signaling promotes CRC stemness and metastasis partly by inducing the stemness markers ALCAM (CD166) and PROM1 (CD133).To further elucidate pathways sustaining CRC stemness, we performed a compound screen of approximately 500 agents using CKPS spheroid cultures. Among them, QNZ—an inhibitor reported to target NF-κB—significantly downregulated ALCAM and PROM1 and markedly suppressed liver metastasis. Unexpectedly, genetic analysis revealed that these effects were independent of canonical NF-κB signaling. Integrating proteomic and RNA-seq analyses, we identified transcription factors GRHL2 and SOX9 as candidates linking spheroid-induced transcriptional changes to QNZ responsiveness. Grhl2 knockout reduced ALCAM expression in CKPS spheroid cultures and impaired liver metastasis. On the other hand, Sox9 knockout or Ctnnb1 knockdown attenuated PROM1 induction in CKPS spheroids, consistent with SOX9 functioning downstream of Wnt/β-catenin signaling.Collectively, these findings reveal the involvement of multiple pathways—including GRHL2- and Wnt/SOX9-mediated regulation—in maintaining CRC stemness and metastatic potential, providing new insights into therapeutic vulnerabilities of metastatic CRC.", "source_company": "Aichi Cancer Center Research Institute", "source_org_type": "研究机构", "row_number": 660, "target_meta": "not available", "MOA_meta": "抑制剂"}, {"drug_name": "novel compounds as multi-targeted MNK inhibitors", "company": "Ferris State University", "org_type": "大学", "target": "MNK1/MNK2 (主要), FLT3, AURKB", "modality": "inhibitor", "importance_level": "低", "total_score": 41, "institution_score": 25, "track_score": 65, "milestone_score": 35, "field_heat_score": 50, "bonus_score": 2, "brief_reason": "化合物为多靶点抑制剂，主要靶向MNK1/2并兼顾FLT3和AURKB，在AML尤其是耐药AML中有潜在协同抗癌作用。大学机构、非临床阶段、仅细胞水平数据导致整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6437", "id": "ZlXM_5wBX1NQZOEH-LO6", "source_drug_name": "novel compounds as multi-targeted MNK inhibitors", "title": "Multi-targeted MNK inhibitors as anticancer agents for AML", "abstract_text": "Mutant FMS-like tyrosine kinase 3 (FLT3) is implicated as an oncogenic driver in over 30% of acute myeloid leukemia (AML) cases. While several FLT3-targeted drugs have been approved, resistance develops rapidly through varied mechanisms, including RAS mutations. The mitogen-activated protein kinase-interacting kinases (MNK1 and MNK2) are the only kinases that phosphorylate the eukaryotic translation initiation factor 4E (eIF4E). Dysregulation of the MNK-eIF4E axis has been seen in acute myeloid leukemia (AML) and MNK inhibitors have shown antiproliferative effects in AML. The kinases, MNK1 and MNK2 are activated by p38 mitogen-activated protein (MAP) kinase and extracellular signal-regulated kinase (ERK), downstream of FLT3 and RAS in the RAS/RAF/ERK signaling cascade. The aurora kinases (AURKA and AURKB) are also overexpressed in AML. Synergistic anticancer effects have been observed in AML for AURK inhibitors in combination with FLT3 targeted drugs. Multitargeted inhibition of varied oncogenic drivers could be anticipated to demonstrate improved anticancer effects in AML, particularly resistant AML. We have identified novel compounds as multi-targeted MNK inhibitors that bind with nanomolar potencies to MNK1, MNK2, FLT3 and AURKB. The compounds show single-digit micromolar inhibition of AML cells expressing mutant FLT3 (MV-411) and are equipotent to tomivosertib, a clinically investigated MNK inhibitor that was included as a standard for comparison. The design, synthesis, and anticancer effects of multi-targeted MNK inhibitors will be described.", "source_company": "Ferris State University", "source_org_type": "大学", "row_number": 719, "target_meta": "MKNK2,MKNK1,Flt3,AURKB", "MOA_meta": "抑制剂"}, {"drug_name": "anti-LSR antibody", "company": "The University of Osaka", "org_type": "大学", "target": "LSR", "modality": "antibody", "importance_level": "低", "total_score": 41, "institution_score": 25, "track_score": 65, "milestone_score": 35, "field_heat_score": 55, "bonus_score": 0, "brief_reason": "anti-LSR antibody靶向LSR抑制α-生育酚摄取从而促进铁死亡，机制新颖但处于大学基础研究阶段。机构为大学得分较低，赛道铁死亡相关+抗体中等，尚无临床前里程碑进展导致总分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9113", "id": "sVXM_5wBX1NQZOEH-LO6", "source_drug_name": "anti-LSR antibody", "title": "LSR suppresses ferroptosis through alpha-tocopherol uptake and promotes tumor growth in gynecological cancers", "abstract_text": "Background\nLipolysis-stimulated lipoprotein receptor (LSR) plays an important role in lipid uptake and is overexpressed in gynecologic cancers, where its high levels are correlated with unfavorable outcomes. However, the lipid metabolic mechanisms via LSR are not well understood. In this study, we investigated how LSR-dependent lipid uptake promotes tumor growth in gynecologic malignancies.\nMethods\nTo explore the lipid metabolic mechanism mediated by LSR, we first demonstrated the effect of high-fat diet (HFD) on tumor growth of LSR-positive ovarian cancer in vivo, and compared the antitumor efficacy of anti-LSR antibody (Ab) between HFD-fed and normal diet (ND)-fed mice. Next, we assessed whether serum from HFD-fed mouse promotes proliferation of ovarian cancer cells in vitro. To identify lipid metabolites responsible for HFD-induced tumor promotion, we performed metabolomic analysis of HFD and ND mouse serum. Based on the identified metabolite, we further investigated its mechanistic contribution to tumor growth.\nResults\nHFD significantly promoted ovarian cancer growth (p < 0.05), and the antitumor effect of anti-LSR Ab was strongly effective in HFD-fed mouse in vivo (p < 0.05). HFD mouse serum also significantly enhanced cell proliferation of ovarian cancer cells in vitro (p < 0.05). Metabolomic analysis of HFD and ND mouse serum identified alpha-tocopherol (vitamin E) as the most discriminative metabolite. Alpha-tocopherol is a lipid-soluble antioxidant known to suppress ferroptosis; thus, we hypothesized that LSR-mediated alpha-tocopherol uptake inhibits ferroptosis in gynecological cancer cells. At first, we demonstrated that LSR knockdown (KD), using siRNA, significantly suppressed cell proliferation in endometrial and ovarian cancer cells (p < 0.05). LSR-KD also reduced GPX4 expression and increased reactive oxygen species (ROS) and lipid peroxidation, indicating enhanced ferroptosis sensitivity. Importantly, these effects were completely reversed by ferroptosis inhibitors but not by apoptosis or necroptosis inhibitors, suggesting that LSR inhibits ferroptosis specifically. In control endometrial and ovarian cancer cells, alpha-tocopherol supplementation restored cell proliferation (p < 0.05), GPX4 expression, and reduced ROS and lipid peroxidation under oxidative stress (H2O2 exposure). However, in LSR-KD cells, alpha-tocopherol did not show a rescue effect, consistent with impaired uptake via LSR.\nConclusion\nLSR promotes tumor progression of gynecological cancers through alpha-tocopherol uptake, leading to ferroptosis suppression. Inhibition of alpha-tocopherol uptake via LSR may sensitize endometrial and ovarian cancers to ferroptosis-inducing treatments.", "source_company": "The University of Osaka", "source_org_type": "大学", "row_number": 772, "target_meta": "LSR", "MOA_meta": "抗体"}, {"drug_name": "Hedgehog Pathway Inhibitor 1", "company": "VANDERBILT UNIVERSITY", "org_type": "大学", "target": "GLI2", "modality": "inhibitor", "importance_level": "低", "total_score": 41, "institution_score": 35, "track_score": 55, "milestone_score": 35, "field_heat_score": 45, "bonus_score": 0, "brief_reason": "药物为GLI2/Hedgehog通路小分子抑制剂，可显著降低骨转移乳腺癌细胞中OPN分泌及基质蛋白表达。机构为大学学术研究、仅工具化合物水平、无临床开发迹象导致整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/7432", "id": "HFXM_5wBX1NQZOEH-LS6", "source_drug_name": "Hedgehog Pathway Inhibitor 1", "title": "Gli2 increases Osteopontin expression to alter cancer associated fibroblast behavior", "abstract_text": "Breast cancer is known to often metastasize into the bone. Among the subtypes, triple negative is the most aggressive. Once the cancer spreads to the bone it activates a positive feedback loop known as the vicious cycle of bone metastasis. In this cycle, Parathyroid hormone-Related protein (PTHrP) is released from tumor cells which activate osteoblasts inducing their expression of Receptor Activator of Nuclear factor Kappa-B Ligand (RANKL). RANKL binds to Receptor Activator of Nuclear factor Kappa-B Ligand (RANK) expressed on osteoclasts, thereby activating the osteoclasts to induce bone resorption subsequently releasing growth factors that fuel the tumor. This can lead to increased risk in bone fractures from the tumor indirectly activating osteoclasts. Chemotherapy is commonly given to patients with breast cancer such as paclitaxel, however, drug resistance often occurs, and treatment becomes less effective, particularly in metastatic disease. Fibroblasts are cells that are responsible for wound healing in normal circumstances. However, in cancer they can transform into Cancer Associated Fibroblasts (CAFs) capable of producing extracellular matrix proteins that surround the tumor which prevents drugs and immunotherapies from reaching the tumor. Our recent studies indicate that a transcription factor from hedgehog signaling known as GLI2 binds is upregulated in response to the chemotherapeutic, paclitaxel. RNA-sequencing analyses showed that increased expression of Gli2 increases genes associated with CAFs including osteopontin (OPN), a secreted glycoprotein. Furthermore, using the JASPAR transcription binding software, we found that Gli2 is predicted to bind to the SPP1 promoter (gene name for OPN) on chromosome 4 at a potential Gli2 binding element. Therefore, we hypothesize that osteopontin secretion is directly regulated by GLI2 in the tumor cells through direct binding of the SPP1 promoter. To test this, we knocked out GLI2 expression in bone metastatic breast cancer cell lines and showed a reduction in OPN secretion. Additional studies with a Gli2 small molecule inhibitor Hedgehog Pathway Inhibitor 1 (HPI-1) showed a 75% reduction in SPP1 by QPCR and a significant reduction of OPN secretion by ELISA. Furthermore, we showed direct changes in the production of collagens and other matrix proteins both by QPCR and immunohistochemistry. In the future, we will directly examine changes in the surrounding fibroblast phenotypes and investigate the impact on drug resistance that CAFs may play in bone metastatic tumors. Taken together, this suggests that Gli2 expressing tumors can increase OPN secretion and this may alter the production of extracellular matrix proteins by the surrounding CAFs.", "source_company": "VANDERBILT UNIVERSITY", "source_org_type": "大学", "row_number": 850, "target_meta": "GLI2", "MOA_meta": "抑制剂"}, {"drug_name": "STE20 inhibitors", "company": "Temple University Lewis Katz School of Medicine", "org_type": "大学", "target": "STE20-family kinase", "modality": "inhibitor", "importance_level": "低", "total_score": 41, "institution_score": 30, "track_score": 60, "milestone_score": 40, "field_heat_score": 50, "bonus_score": 0, "brief_reason": "STE20家族激酶抑制剂针对NSCLC中partial EMT机制，潜在逆转EMT并增敏铂类化疗，但靶点未明确具体成员。大学机构研发处于机制探索阶段，无临床进展，赛道有一定Hippo相关热度但整体开发早期。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6054", "id": "P1XM_5wBX1NQZOEH-LS6", "source_drug_name": "STE20 inhibitors", "title": "Identification of protein kinase signaling networks activating partial EMT as therapeutic targets in non-small cell lung cancer", "abstract_text": "Non-small cell lung cancer (NSCLC), of which one-third are lung squamous cell carcinomas (LUSC), is the leading cause of cancer-related death in the US. LUSC treatments primarily involve platinum-based chemotherapy and immune checkpoint blockade. However, only 20% of patients benefit long-term, underscoring a critical need for strategies that improve treatment efficacy. We have identified partial epithelial-to-mesenchymal transition (pEMT) as a key mechanism hindering treatment efficacy in LSCC. pEMT is a cell state in which cancer cells display epithelial and mesenchymal characteristics, and is associated with heightened cell migration/invasion, survival, and treatment resistance. Therefore, we sought to identify phosphorylation networks that could reverse pEMT and, thereby, sensitize LSCC to treatment. We have identified a STE20-family kinase network as a central signaling node sustaining pEMT in LSCC cells. RNAseq analysis of STE20-inhibited LSCC cells revealed transcriptional reprogramming of LSCC indicative of reversion to an epithelial-like phenotype. Consistently, we observed increased expression of epithelial markers (E-cadherin, EpCAM), and reduced levels of mesenchymal markers (vimentin, CD44). Furthermore, STE20 depletion or inhibition suppressed key pEMT functions, including migration, invasion, and clonogenic potential. Our current studies are aimed at identifying the underlying mechanisms of the observed phenotypes. Our initial analysis indicates that STE20 is required for the activation of the YAP/TAZ and MYC transcriptional programs. Last, to lay the groundwork for combination treatments, we conducted a high-throughput screen using a library of clinically relevant compounds in combination with STE20 inhibitors. This screen showed potential synergism with platinum-based chemotherapy, which we are investigating in vitro and in vivo. In conclusion, we have uncovered a STE20 phosphorylation module that sustains pEMT in NSCLC cells and represents an actionable vulnerability that can be targeted to sensitize NSCLCs to first-line treatments.", "source_company": "Temple University Lewis Katz School of Medicine", "source_org_type": "大学", "row_number": 876, "target_meta": "not available", "MOA_meta": "抑制剂"}, {"drug_name": "SR-A antagonist", "company": "University of Arkansas for Medical Sciences", "org_type": "大学", "target": "SR-A", "modality": "inhibitor", "importance_level": "低", "total_score": 41, "institution_score": 25, "track_score": 55, "milestone_score": 45, "field_heat_score": 50, "bonus_score": 3, "brief_reason": "SR-A antagonist通过阻断SR-A重编程TAMs向抗原呈递表型转变，并与CD137激动剂协同增强抗肿瘤免疫，但仅为大学机构的动物实验研究。机构非商业公司、仍处于早期体内验证阶段导致总体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5150", "id": "NJ7M_5wBZznHJdnt_W3O", "source_drug_name": "SR-A antagonist", "title": "SR-A antagonism remodels the myeloid population of tumor immune microenvironment, expands CD8-positive T cells, and enhances antitumor efficacy in vivo", "abstract_text": "Introduction: Tumor-associated macrophages (TAMs) are key regulators of the tumor immune microenvironment (TIME). Macrophage class A scavenger receptors (SR-A) modulate macrophage activation and polarization, and increased SR-A-positive TAMs are associated with poor outcomes in several cancers, including breast cancer. We previously showed that SR-A engagement skews macrophages toward an immunosuppressive phenotype, suggesting that SR-A blockade may reprogram the TIME and enhance antitumor immunity. In this study, we tested whether SR-A blockade reprograms the TIME and limits tumor progression in tumor-bearing mice.\nMethods: EO771 cancer cells were injected into mammary fat pads of syngeneic mice to establish breast tumors. Tumor-bearing mice were treated with an SR-A antagonist or a control, and then CD45⁺ tumor-infiltrating cells were isolated for single-cell RNA sequencing. In separate cohorts, SR-A blockade was combined with CD137-targeted activation, and mice were euthanized when tumors reached the predefined tumor endpoint (volume ≥ 1.5 cm³). In parallel, mice were treated with the appropriate controls for both SR-A antagonist and CD137 activation. Tumor volume, time to the tumor endpoint, and the presence of lung metastases were determined. Mice showing complete tumor regression were rechallenged by assessing tumor growth following the injection of EO771 cells into the contralateral mammary fat pad.\nResults: Monotherapy with the SR-A antagonist did not significantly alter primary tumor growth. However, single-cell RNA-seq of CD45⁺ tumor-infiltrating cells indicated a shift in the polarization of tumor-associated macrophages toward an immunostimulatory, antigen-presenting phenotype, characterized by the upregulation of MHC class II molecules. Further, there was an increase in a cytotoxic T-cell subset characterized by high expression of the CD137 co-stimulatory receptor. Extending these results, we evaluated the effect of combining the SR-A antagonist with targeted CD137 activation. Treating tumor-bearing mice with the combination of SR-A antagonist and CD137 activation significantly inhibited both tumor growth and the proportion of mice that developed lung metastases compared to control-treated mice. Moreover, a subset of treated mice achieved complete tumor regression and rejected subsequent tumor rechallenge, consistent with the generation of durable systemic antitumor immune memory.\nConclusions: Inhibiting SR-A-dependent interactions reprograms macrophages toward a tumor-hostile, antigen-presenting phenotype, enhances cytotoxic T-cell responses, and synergizes with CD137-targeted activation. Thus, SR-A-blocking strategies may improve the efficacy of co-stimulatory receptor agonists by conditioning the TIME.", "source_company": "University of Arkansas for Medical Sciences", "source_org_type": "大学", "row_number": 984, "target_meta": "not available", "MOA_meta": "抑制剂"}, {"drug_name": "selective MMP-9 inhibitors", "company": "Mayo Clinic Florida", "org_type": "医院", "target": "MMP-9", "modality": "inhibitor", "importance_level": "低", "total_score": 41, "institution_score": 40, "track_score": 50, "milestone_score": 30, "field_heat_score": 40, "bonus_score": 0, "brief_reason": "药物针对MMP-9，通过蛋白工程实现选择性抑制，针对三阴性乳腺癌具有潜在治疗策略，但摘要被禁运未披露具体细节。机构为医院/学术型，得分较低；赛道为经典靶点但非当前最热，开发阶段仅体现preclinical概念性，无明确里程碑进展导致总分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11649", "id": "s57M_5wBZznHJdnt_W3O", "source_drug_name": "selective MMP-9 inhibitors", "title": "Protein engineering of selective MMP-9 inhibitors reveals a therapeutic strategy for triple-negative breast cancer", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Mayo Clinic Florida", "source_org_type": "医院", "row_number": 1076, "target_meta": "MMP9", "MOA_meta": "抑制剂"}, {"drug_name": "miR-342-5p", "company": "NIH-NCI", "org_type": "政府机构", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 41, "institution_score": 35, "track_score": 45, "milestone_score": 40, "field_heat_score": 50, "bonus_score": 0, "brief_reason": "miR-342-5p为肿瘤抑制性microRNA，在DPM中下调，重新表达可诱导细胞凋亡并抑制肿瘤生长，但靶点未明确披露。机构为政府研究单位、处于早期机制探索阶段且未进入药物开发，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/2340", "id": "Hp7M_5wBZznHJdnt_W7O", "source_drug_name": "miR-342-5p", "title": "miR-342-5p: A promising tumor suppressor in diffuse pleural mesothelioma", "abstract_text": "Diffuse pleural mesothelioma (DPM) is an incurable, aggressive neoplasm with limited therapies. Moving beyond conventional approaches, we posit that microRNAs (miRNA), short, non-coding RNA that coherently regulate gene expression, can uniquely disrupt the molecular networks involved in DPM. In this study, we identified miR-342-5p as a novel DPM-associated miRNA. We used a human miRNA mimic library to screen for miRNAs with antiproliferative effects on a panel of DPM cell lines. Among the most potent candidates was miR-342-5p. We profiled the downregulation of miR-342-5p in DPM patient specimens compared to normal pleura (Normal=22, Tumor=50). TCGA-MESO analysis revealed that miR-342-5p downregulation is significantly associated with poor survival outcomes. Our results demonstrated that the re-expression of miR-342-5p significantly impaired DPM cell viability, reduced 2D colony foci formation, and inhibited anchorage-independent cell growth in soft-agar and sphere assays. Additionally, Annexin-V assays showed a significant increase in early and late apoptotic cells in miR-342-5p transfected DPM cells compared to controls. Furthermore, we confirmed the induction of apoptosis in miR-342-5p-treated DPM cells through PARP cleavage and the activation of caspase-3/7. Importantly, no significant biological effects were observed when normal human mesothelial cells (NP1 line) were treated with miR-342-5p. Next, we performed a Biotin-miRNA (Bi-miR) pull-down assay, a direct binding assay in which a biotin-tagged miR-342-5p probe captures its associated mRNA transcripts in a pooled lysate. Then, RNA-seq analysis is conducted to identify direct target genes associated with apoptosis and cell death pathways in DPM. We identified the top transcripts targeted by miR-342-5p that are also involved in its tumor-suppressive activity in DPM. Overall, our findings highlight the tumor suppressive effects and therapeutic potential of miR-342-5p for DPM treatment.", "source_company": "NIH-NCI", "source_org_type": "政府机构", "row_number": 1146, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "pH-targeted gadolinium-based nanoparticles", "company": "Stanford University", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 41, "institution_score": 35, "track_score": 45, "milestone_score": 40, "field_heat_score": 50, "bonus_score": 0, "brief_reason": "该产品为pHLIP偶联的钆基纳米颗粒，主要利用酸性肿瘤微环境靶向增强MRI显像和放疗增敏，但靶点未明确披露，属于成像/增敏剂类other modality。斯坦福大学学术机构研发，处于早期preclinical阶段且本次研究未显示放疗增效提升，整体开发热度和里程碑价值有限。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3911", "id": "aZ7M_5wBZznHJdnt_W7P", "source_drug_name": "pH-targeted gadolinium-based nanoparticles", "title": "pH-targeted gadolinium-based nanoparticles for enhanced radiotherapy", "abstract_text": "Gadolinium-based nanoparticles (GdNP) are sub-5 nm particles designed for radiosensitization and MRI contrast enhancement. The high atomic number of Gd (Z = 64) enables efficient X-ray absorption and dose deposition within tumors, with tumor accumulation facilitated by the enhanced permeability and retention effect. Previous clinical trials have provided preliminary evidence for the safety and potential therapeutic benefit of intravenous GdNP in patients with cervical cancer and brain metastases. To improve tumor specificity, we conjugated GdNP with pH-low insertion peptide (pHLIP), which targets the acidic tumor microenvironment through pH-dependent membrane insertion. Previous work demonstrated that pHLIP conjugated to GdNP enhanced gadolinium uptake and radiosensitization in vitro. In vitro experiments were performed with cultured A549 human lung adenocarcinoma cells at pH 6.2 (tumor-like) and pH 7.4 (physiologic) conditions. Clonogenic assays and ICP-MS analysis revealed that while pHLIP-GdNP (0.17 mM dose) did not significantly alter cell survival, it increased intracellular gadolinium levels by approximately 18-fold under acidic conditions compared to unconjugated GdNP. In vivo, mice bearing subcutaneously implanted A549 tumors received 10 Gy X-ray irradiation with or without unconjugated GdNP or pHLIP-GdNP pretreatment (300 mg/kg; n = 7 mice/group). All irradiated groups exhibited significant tumor growth delay compared to controls (P < 0.013), but no additional radiosensitization was observed in the nanoparticle-treated cohorts, despite Gd accumulation in the tumor. MRI T1 mapping demonstrated shortened T1 relaxation times following GdNP administration, with greater reduction following pHLIP-GdNP injection, indicating enhanced contrast agent delivery. These findings suggest that pHLIP conjugation improves gadolinium uptake and MRI visibility but does not enhance radiotherapeutic efficacy under current conditions. Departing from previous work, this study used a simpler covalent bond to conjugate pHLIP to GdNP rather than a disulfide bridge, which may explain the decreased efficacy. Reintroducing the disulfide linkage might be critical, as it allows the conjugate to remain stable in circulation while releasing nanoparticle cargo upon insertion into acidic tumor cells, potentially increasing therapeutic efficacy.", "source_company": "Stanford University", "source_org_type": "大学", "row_number": 1193, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "polyIC", "company": "University of California San Diego", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 40.8, "institution_score": 35, "track_score": 40, "milestone_score": 45, "field_heat_score": 50, "bonus_score": 3, "brief_reason": "polyIC为合成dsRNA，主要用于诱导免疫反应而非直接靶向特定分子靶点，机制涉及TNFα产生的中性粒细胞亚群。大学机构+基础机制研究阶段导致整体重要性较低，仅在老年肝毒性机制上有一定亮点。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5333", "id": "vVXM_5wBX1NQZOEH-LG6", "source_drug_name": "polyIC", "title": "A TNF-producing neutrophil subset drives age-dependent hepatotoxicity", "abstract_text": "The mechanisms by which aging contributes to the detrimental effect of cancer therapy remain poorly understood. Herein we show that while a synthetic dsRNA (polyIC) effectively suppresses liver tumors in young mice, it induces lethal liver necrosis in aged mice. Single-cell and functional analyses unearthed a CD14⁺ neutrophil subset featured by robust TNFα induction by polyIC exclusively in the aged liver. Impaired NR3C1 expression and elevated NF-κB and AP-1 signaling drive a skewing toward Tnf⁺ over Saa1⁺ neutrophils in the aged liver. TNF neutralization rescued polyIC-induced mortality, while also enhancing its antitumor effect in aged mice. Bioinformatic analysis revealed significant association of a Tnf⁺Saa1⁻ neutrophil gene signature with reduced survival in liver cancer patients over 60. This study uncovers a previously unknown detrimental mechanism in the aged liver, which is undetectable under basal conditions. We provide a new strategy to improve therapeutic outcomes in elderly patients by mitigating treatment-associated toxicity.", "source_company": "University of California San Diego", "source_org_type": "大学", "row_number": 443, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "B7-H3 targeted microbubbles", "company": "Stanford University", "org_type": "大学", "target": "B7-H3", "modality": "other", "importance_level": "低", "total_score": 40.5, "institution_score": 35, "track_score": 45, "milestone_score": 40, "field_heat_score": 50, "bonus_score": 0, "brief_reason": "药物为靶向B7-H3的微泡超声造影剂，用于肾癌血管内皮早期诊断成像，靶点B7-H3在肿瘤微环境有表达。斯坦福大学学术项目处于早期可行性验证阶段，诊断成像工具在热门靶向治疗赛道外重要性有限，综合热度和开发里程碑均较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8543", "id": "xFXM_5wBX1NQZOEH-LG6", "source_drug_name": "B7-H3 targeted microbubbles", "title": "Renal cancer early diagnosis using a novel B7-H3 targeted ultrasound contrast imaging", "abstract_text": "Aim: Cost-effective or accessible methods to detect kidney cancers, especially those with renal insufficiency, remain elusive. We propose ultrasound molecular imaging (UMI) using microbubbles (MBs) targeted to cancer-associated vascular endothelial (VE) markers as a diagnostic imaging tool for kidney cancer with high specificity. CD276 (B7-H3), an immune checkpoint (IC) marker and a member of the immunoglobulin superfamily, is overexpressed on the VE cells of different cancers including renal cancer.\nMethods: We have developed an engineered affibody (Aby) specifically targeting both mouse and human B7-H3 for imaging renal cancer in vivo using US. In this study, we biotinylated the Aby and linked to MBs that were functionalized with avidin to create B7-H3 targetable MBs (TMBs) or with a scrambled Aby not binding to B7-H3 as a control MBs (non-targeted MBs or NTMBs), yielding (10 x 108 MBs/mL). Balb/C mice (n=4) were implanted with renca kidney cancer cells at the lower flank for in vivo imaging of VE-B7-H3 expression in the tumor. We also performed immunofluorescence (IF) analysis of the tumor tissue for the presence of B7-H3 and CD31 on VE cells at the vessels in the tumor microenvironment (TME).\nResults: Mice were imaged after tumor growth reached to 0.8-1.1 mm diameter with UMI, after administration of 1-2 x107 TMBs or NTMBs in 200 µL of saline. Compared to control NTMBs, the UMI signal using B7-H3-targeted TMBs was significantly higher (P= 0.002). IF analysis confirmed a high correspondence between B7-H3 and the universal vascular CD31 marker.\nConclusions: The developed TMBs were able to detect and image the in vivo expression of tumor-associated B7-H3 in the VE cells. The results support the feasibility of these B7-H3-TMBs in translating into human kidney cancer diagnosis using UMI.", "source_company": "Stanford University", "source_org_type": "大学", "row_number": 449, "target_meta": "CD276", "MOA_meta": "其他"}, {"drug_name": "PINK1 inhibitor", "company": "King Abdullah International Medical Research Center", "org_type": "研究机构", "target": "PINK1", "modality": "inhibitor", "importance_level": "低", "total_score": 40.5, "institution_score": 25, "track_score": 45, "milestone_score": 55, "field_heat_score": 40, "bonus_score": 0, "brief_reason": "PINK1抑制剂针对线粒体自噬通路，在SHH型髓母细胞瘤模型中通过药理和遗传抑制显著延长生存并减轻肿瘤负担。机构为研究机构非头部药企、靶点与赛道非当前热门、仅停留在动物模型阶段导致总分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1788", "id": "sFXM_5wBX1NQZOEH-LO6", "source_drug_name": "PINK1 inhibitor", "title": "Genetic and pharmacologic suppression of pink1 prolongs survival in sonic hedgehog driven medulloblastoma and related mouse model", "abstract_text": "Mitochondrial quality control plays a key role in helping cancer cells survive, but its impact on medulloblastoma is still not well understood. Here, we examined how the mitochondrial kinase PINK1 contributes to medulloblastoma growth by blocking its activity pharmacologically and by genetic loss-of-function approaches in mouse brain tumor models. Human medulloblastoma cells, MB004 and D425, were pretreated with a PINK1 inhibitor prior to orthotopic implantation. Kaplan-Meier analysis demonstrated significantly prolonged survival in mice receiving PINK1-inhibited tumor cells compared with controls (MB004: p = 0.0288; D425: p = 0.0284), indicating that disruption of PINK1 enhances therapeutic vulnerability. To further assess the role of Pink1 in vivo, we generated a genetically engineered mouse model without Pink1 in a Trp53-/-; Ptch1+/- background. This is a spontaneous tumor formation model at 90% rate. Pink1 deletion significantly increased survival compared with Pink1-active Trp53-/-; Ptch1+/- mice (p = 0.0491), supporting a tumor-promoting role for Pink1 in Sonic Hedgehog-driven medulloblastoma. Histopathological analysis of hematoxylin and eosin stained brain sections presented normal brain structure in the control animals, while Trp53-/-; Ptch1+/- mice developed high-grade tumors. Interestingly, Trp53-/-; Ptch1+/-; Pink1-/- brains showed reduced tumor burden and retained more tissue structure, consistent with the observed survival advantage. Together, these findings demonstrate that PINK1 is required for efficient medulloblastoma growth and that its inhibition—either through acute pharmacologic targeting or permanent genetic disruption—improves survival and reduces tumor pathology. Targeting mitophagy pathways such as disruption of PINK1 activity may therefore represent a promising therapeutic strategy for medulloblastoma, particularly in resistant or high-risk disease.", "source_company": "King Abdullah International Medical Research Center", "source_org_type": "研究机构", "row_number": 771, "target_meta": "PINK1", "MOA_meta": "抑制剂"}, {"drug_name": "C60-ser", "company": "UT Health Houston", "org_type": "医院", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 40.5, "institution_score": 35, "track_score": 45, "milestone_score": 40, "field_heat_score": 50, "bonus_score": 3, "brief_reason": "C60-ser为富勒烯衍生物，通过Nrf2-ARE通路激活抗氧化酶实现选择性辐射防护，靶点机制未直接针对特定分子。机构为医院学术型、处于早期研究阶段、赛道非主流热门导致整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3944", "id": "JFXM_5wBX1NQZOEH-LS6", "source_drug_name": "C60-ser", "title": "Radioprotective fullerene derivative as a potential systemic therapeutic to alleviate radiation-induced cardiovascular disease", "abstract_text": "Despite advances in radiation therapy (RT), radiation-induced cardiovascular disease remains a major cause of long-term morbidity and mortality in cancer survivors, increasing cardiovascular risk by 10-30% within 5-10 years after treatment. Excess reactive oxygen species (ROS) are major drivers of RT-induced endothelial injury and cardiovascular dysfunction, causing direct oxidative damage to DNA, lipids, and proteins and activating inflammatory pathways that sustain endothelial dysfunction. Targeting ROS-mediated injury, therefore, represents a promising strategy to mitigate the cardiovascular toxicity of radiation therapy. Fullerenes (C60) and their derivatives are potent antioxidants and are referred to as \"free radical scavengers\" because of their ability to readily interact with and neutralize free radicals. Despite promising reports of the antioxidant and anti-inflammatory activity of C60 fullerenes in recent years, translating C60 into clinic application is challenging due to their inherent lipophilicity and insolubility in aqueous media. To address this challenge, we have developed a novel chemistry for the custom synthesis of C60 derivatized with serinol (C60-ser). This derivative is neutral, amphiphilic and exquisitely soluble in water. Our data demonstrated that C60-ser is non-toxic and can protect non-malignant normal endothelial cells, but not cancer cells, from RT-mediated damage. Mechanistically, C60-ser radioprotection is exerted by both neutralizing RT-induced free radicals and inducing antioxidant response pathway and activity of antioxidant enzymes to neutralize RT-induced free radicals. The resultant radioprotective effects include preservation of mitochondrial respiratory capacity and reduction in DNA damage, senescence, and inflammatory responses of endothelial cells, which together enhance the long-term cell survival after RT. Remarkably, C60-ser treatment upregulates the expression of the transcription factor Nrf2 and promotes its nuclear translocation, thereby activating the Nrf2-antioxidant response element (ARE) signaling axis for the expression of downstream antioxidant enzymes (catalase, SOD2, HO-1, NQO1, and TRX1) in normal cells but not in cancer cells. Collectively, these results highlight a critical role of the Nrf2-ARE pathway in mediating the effects of C60-ser against oxidative stress. This study advances the realization of the clinical translation of C60-ser for reducing RT-induced toxicity in cardiovascular tissues of cancer patients.", "source_company": "UT Health Houston", "source_org_type": "医院", "row_number": 856, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "MBQ-168", "company": "University of Puerto Rico Medical Sciences Campus", "org_type": "大学", "target": "Rac and Cdc42", "modality": "inhibitor", "importance_level": "低", "total_score": 40.5, "institution_score": 25, "track_score": 60, "milestone_score": 45, "field_heat_score": 50, "bonus_score": 0, "brief_reason": "MBQ-168为Rac和Cdc42双靶点小分子抑制剂，针对PDAC同时作用肿瘤细胞与免疫抑制性巨噬细胞。机构为大学、仅体外+初步小鼠原位模型、preclinical早期阶段导致综合评分较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5719", "id": "op7M_5wBZznHJdnt_W3O", "source_drug_name": "MBQ-168", "title": "Potential of Rac and Cdc42 inhibitors as pancreatic cancer therapeutics", "abstract_text": "Pancreatic ductal adenocarcinoma (PDAC) remains one of the deadliest forms of cancer, with a distinct extracellular matrix and immunosuppressive tumor microenvironment. Existing chemotherapies are hampered by toxicity and demonstrate poor clinical response. Therapies targeting the KRAS G12D mutation, prevalent in pancreatic cancer, have yet to receive FDA approval. Therefore, there is a critical need for novel targeted therapies for PDAC. These therapies should simultaneously target metastatic cancer cells and immunosuppressive cells such as tumor-associated macrophages (TAMS), since they promote pancreatic cancer progression. Ras-activated related GTPases Rac and Cdc42 are ideal targets for pancreatic cancer therapy because they regulate migration, invasion, polarity, viability, and survival in cancer cells and immune cells. Therefore, we developed Rac and Cdc42 inhibitors for metastatic diseases such as PDAC to target cancer and its immunosuppressive environment. The hypothesis tested in this study is that Rac/Cdc42 inhibitors will simultaneously target the migration and activity of cancer cells and macrophage-like cells in the TME.  We assessed the potential of the dual Rac and Cdc42 inhibitors MBQ-167 and MBQ-168, which block guanine nucleotide association with Rac and Cdc42. The effects of vehicle, MBQ-167 or MBQ-168 were tested in human and mouse PDAC cells or macrophages by performing pulldown assays for Rac and Cdc42 activation, MTT assays for cell viability, wound-healing assays for cell migration, phagocytosis, as well as co-culture assays with PDAC cells and macrophages. Results demonstrated that Rac and Cdc42 inhibitors significantly reduced active Rac and Cdc42 in pancreatic and macrophage cells. Both MBQ-167 and MBQ-168 reduced pancreatic cancer cell viability, without affecting macrophage viability, and inhibited cell morphology and migration. In co-culture using Transwells, MBQ-167 and MBQ-168 decreased pancreatic cancer cell migration from the top wells, with macrophages in the bottom wells, and reduced inflammatory mediators such as IL-6, CHI3L1 and S100A8 and S100A9 levels in conditioned media. A preliminary study was also conducted in C57BL6 mice bearing orthotopic KPC (KRas G12D, p53 null, Cre) tumors to test the effect of vehicle or 10mg MBQ-167 administered by IP 5X a week for 21 days. MBQ-167 treatment decreased tumor growth and increased survival compared to vehicle treatments.  In conclusion, MBQ-167 and MBQ-168 pose as potential therapeutics for PDAC due to their ability to target both pancreatic and macrophage-like cells.", "source_company": "University of Puerto Rico Medical Sciences Campus", "source_org_type": "大学", "row_number": 1061, "target_meta": "RAC,CDC42", "MOA_meta": "抑制剂"}, {"drug_name": "proteasome inhibitors", "company": "Auburn University", "org_type": "大学", "target": "未披露", "modality": "inhibitor", "importance_level": "低", "total_score": 39.8, "institution_score": 25, "track_score": 65, "milestone_score": 35, "field_heat_score": 45, "bonus_score": 3, "brief_reason": "proteasome inhibitors为成熟靶点抑制剂类药物，本研究发现snoRNA在PI诱导凋亡中的新作用，属于基础机制探索。大学机构+preclinical机制研究+已有成熟药物背景下，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/2316", "id": "mFXM_5wBX1NQZOEH-LS6", "source_drug_name": "proteasome inhibitors", "title": "A novel role of snoRNAs in proteasome inhibitor induced apoptosis", "abstract_text": "Small nucleolar RNAs (snoRNA) are 60-300 nucleotide long RNAs that guide modification of rRNAs during ribosome biogenesis. Many of them have non-canonical functions, such as regulation of splicing, pseudouridylation, and 2’-O-methylation of specific mRNAs. We have made a serendipitous discovery that treatment of cells with proteasome inhibitors (PIs) induces expression of several snoRNAs, including SNORD3 and SNORA71 families. Two other agents that induce production of misfolded proteins, tunicamycin and thapsigargin, also induced these snoRNAs, but DNA-damaging agent doxorubicin did not. Knocking SNORA71D down reduced PI-induced apoptosis. These findings indicate a novel and unexpected role of snoRNAs in proteasome inhibitor induced apoptosis.", "source_company": "Auburn University", "source_org_type": "大学", "row_number": 941, "target_meta": "not available", "MOA_meta": "抑制剂"}, {"drug_name": "gamma-secretase inhibitor", "company": "University of Mississippi Medical Center", "org_type": "医院", "target": "Notch", "modality": "inhibitor", "importance_level": "低", "total_score": 39.5, "institution_score": 25, "track_score": 65, "milestone_score": 35, "field_heat_score": 50, "bonus_score": 0, "brief_reason": "药品为gamma-secretase inhibitor，靶向Notch信号通路，在CAC来源的PDAC干细胞样亚群中显示独特敏感性。机构为大学医院，preclinical阶段仅动物模型和organoid水平，赛道有一定热度但整体开发价值有限。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/704", "id": "DlXM_5wBX1NQZOEH-LG5", "source_drug_name": "gamma-secretase inhibitor", "title": "Uncovering a pancreatic ductal adenocarcinoma sub-population with stemness and unique therapeutic response", "abstract_text": "Pancreatic ductal adenocarcinoma (PDAC) remains one of the most lethal malignancies, primarily due to its detection at advanced stages, with therapy resistance being the second major cause, leading to limited treatment options. It is well established that pancreatic differentiation is controlled by Notch during organogenesis, and its reactivation is seen in pancreatic tumorigenesis. The regulation of Notch signaling and its relationship with pancreatic exocrine and endocrine cells in pancreatic cancer is still unclear. Therefore, this study was designed to investigate the role of Notch in PDAC initiation and progression with respect to different cells of origin, along with a significant focus on understanding the potential of these cells to behave like cancer stem cells. The two different types of PDAC cells, derived from primary mouse tumors with Kras mutation and p53 deletion, were tested for their sensitivity to various pharmacological inhibitors. These cells originated from Lunatic Fringe (Lfng)-expressing centroacinar cells (CAC) and Mist1-expressing acinar cells. The subsets of Lfng+ tumor cells in these two types of PDAC were sorted for the tests in comparison with their Lfng- counterparts. The protein expression of Notch receptors was analyzed along with their downstream targets. The cells isolated from mice harboring PanIN lesions (not yet developed into PDAC) were examined for their organoid-forming capability to trace which lineage of PDAC cells carries the stem-like properties. Finally, the organoids were analyzed for various markers of pancreatic progenitors and stem-like characteristics to gain insight into the subset of pancreatic cells involved in the initiation of PDAC. It was found that the PDAC cells derived CAC population has an inherent property of behaving as cancer stem-like cells. These cells were highly resistant to the inhibitory effects of the chemotherapy drug gemcitabine compared to acinar-derived PDAC cells. However, they were uniquely sensitive to a gamma-secretase inhibitor, which blocks Notch activation. High expression of Notch3 and Hes1 was predominantly found in the CAC-derived PDAC cells, along with the high efficiency in forming 3D organoids, even at the early stage of tumor initiation. The organoids were found to co-express ductal (CK19) and acinar (Amylase) cell markers, containing cells expressing the pancreatic progenitor marker (Pdx1), stem cell marker (Aldh1a1), and Vimentin-expressing cells, which represent a more aggressive and metastatic subpopulation. These findings hold significant potential in unraveling treatment options and screening patients based on the subtype of the PDAC population. The full potential of GSI needs to be explored for its use as a treatment option alongside other available chemotherapy drugs. Targeting Lfng-dependent Notch signaling may offer an option for treating patients with CAC-derived PDAC.", "source_company": "University of Mississippi Medical Center", "source_org_type": "医院", "row_number": 5, "target_meta": "Notch", "MOA_meta": "抑制剂"}, {"drug_name": "mCPX", "company": "Purdue University", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 39.5, "institution_score": 25, "track_score": 45, "milestone_score": 55, "field_heat_score": 50, "bonus_score": 3, "brief_reason": "mCPX为ciclopirox铁螯合前药衍生物，通过诱导EBV潜伏-裂解周期转换发挥抗EBV+胃癌作用，靶点机制未明确特异性分子靶点。大学早期体外+异种移植瘤研究，赛道非主流热门，综合重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1476", "id": "jVXM_5wBX1NQZOEH-LG6", "source_drug_name": "mCPX", "title": "Targeting lytic cycle with ciclopirox derivative in Epstein-Barr Virus+ gastric cancer", "abstract_text": "Epstein-Barr Virus (EBV) is a ubiquitous human herpesvirus that infects around 90% of the global adult population. Upon infection, the virus typically establishes latency within the host cell, expressing viral genes that promote tumorigenesis, inhibit apoptosis, and suppress immune recognition of infected cells. Induction therapy was introduced to counter these effects by driving the switch from latent to lytic phase, which is a process called lytic reactivation. This transition results in cell lysis with viral particle release and the expression of viral proteins that can be targeted by antiviral agents and the immune system. Here, we developed a novel in-silico drug prediction method to identify compounds capable of inducing the EBV lytic cycle in various EBV+ epithelial malignancies. In vitro treatment of top candidates has successfully triggered lytic reactivation on EBV+ gastric cancer cell lines, namely, SNU719 and AGSBX1. Among these candidates, Ciclopirox (CPX), a clinically used antimycotic agent that has a fungistatic and iron chelation capability, showed strong activity in inducing the EBV lytic cycle, inhibiting proliferation and survival of EBV+ gastric cancer cells by blocking the cell cycle. RNA sequencing revealed that CPX-mediated lytic induction acts primarily through the hypoxia pathway, specifically via hypoxia-inducible factor 1-alpha (HIF1α). CPX treatment increased HIF1α binding to chromatin regions associated with genes involved in gastric cancer proliferation and migration. Co-treatment with a HIF1α inhibitor abolished both the cytotoxic and lytic-inducing effects of CPX, confirming the pathway’s central role. Despite its efficacy, a major limitation of CPX is its instability. During CPX administration, excess iron from both intracellular and extracellular environments will lead to degradation and inactivation of CPX. Co-treatment with equal molarity of ferric ion has completely abolished the lytic-inducing ability of CPX. To address this, we adopt the pro-drug strategy by adding a protective group on CPX, creating a protected derivative mCPX. mCPX has shown comparable activity in lytic induction, while significantly improved resistance toward iron-mediated inactivation compared to CPX or another published pro-drug fosciclopirox. Finally, in an SNU719 xenograft, mCPX demonstrated superior in vivo anti-tumor activity relative to CPX. Altogether, using in-sillico drug prediction platform, we have successfully repurposed CPX as a lytic-induction-based anti-tumor agent against EBV+ gastric cancer, and developed the pro-drug mCPX to enhance its in vivo stability.", "source_company": "Purdue University", "source_org_type": "大学", "row_number": 185, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "statins", "company": "Columbia University Irving Medical Center", "org_type": "医院", "target": "HMGCR", "modality": "inhibitor", "importance_level": "低", "total_score": 39.5, "institution_score": 25, "track_score": 45, "milestone_score": 55, "field_heat_score": 40, "bonus_score": 2, "brief_reason": "药品为他汀类（statins），真实靶点HMGCR，通过抑制SREBP通路和mevalonate途径展现对3q增益鳞癌的合成致死效应。机构为大学医院系统、赛道为老药新用+代谢脆弱性、仅preclinical阶段且非新型分子导致整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4683", "id": "GlXM_5wBX1NQZOEH-LG5", "source_drug_name": "statins", "title": "Aneuploidy as a metabolic liability: Exploiting novel therapeutic targets in squamous cell carcinomas", "abstract_text": "Squamous cell carcinomas (SCCs) across epithelial tissues of the lung, head and neck, and esophagus lack canonical oncogenic mutations and urgently require therapeutic strategies. Aneuploidy—chromosomal gains or losses, is detrimental in normal cells yet occurs in >90% of solid tumors in tissue-specific patterns. SCCs exhibit near-universal chromosome 3q gain, which associates with progression, metastasis, and therapy resistance; however, the mechanisms linking aneuploidies to tumorigenesis remain unclear. To investigate aneuploidy-driven dependencies, we engineered isogenic human lung epithelial cells modeling chromosome 3 disomy and 3q gain and performed genome-wide CRISPRi and drug-repurposing screens. Both screens converged on a lipid metabolism dependency specific to 3q gain, with heightened sensitivity to disruption of the sterol regulatory element-binding protein (SREBP) pathway. SREBF1 emerged as the top genetic hit, while statins (HMGCR inhibitors), were the strongest chemical hits and preferentially induced apoptosis in 3q gain cells. Rescue with mevalonate confirmed on-target effects and additional cholesterol-lowering drugs also induced increased cytotoxicity. Transcriptomic and lipidomic profiling revealed altered cholesterol and fatty acid biosynthesis programs and distinct lipid composition in 3q gain cells. Protein and immunofluorescence analyses further demonstrated impaired SREBP1 activation in 3q gain cells. To identify potential causal gene drivers, we performed a chromosome 3q-focused CRISPRi screen alongside SREBP/HMGCR inhibition. This screen revealed multiple gene candidates—including TFG, SEC62, SERP1, and RAB43—whose knockdown rescued drug-induced loss of viability, implicating ER-to-Golgi transport and cellular stress pathways in altered SREBP1 activation. Ongoing studies are determining whether these mechanisms directly explain reduced pathway activation in 3q gain cells. To assess translational relevance, we validated these dependencies in isogenic organoids and SCC cell lines. In vivo xenograft studies demonstrated that 3q gain SCC tumors exhibit increased sensitivity to suppression of SREBF1 and HMGCR, leading to reduced tumor volume and weight. These findings support chromosome 3q gain as a biomarker of pathway inhibitor response. Together, our results define an aneuploidy-driven, targetable metabolic vulnerability in SCC. Chromosome 3q gain imposes a metabolic cost that creates actionable therapeutic dependencies, nominating lipid metabolism and mevalonate pathway regulators as precision therapy targets for aneuploid SCC.", "source_company": "Columbia University Irving Medical Center", "source_org_type": "医院", "row_number": 327, "target_meta": "HMG-CoA reductase", "MOA_meta": "抑制剂"}, {"drug_name": "anti-HER2 ADCs", "company": "Memorial Sloan Kettering Cancer Center", "org_type": "医院", "target": "HER2", "modality": "ADC", "importance_level": "低", "total_score": 39.5, "institution_score": 35, "track_score": 85, "milestone_score": 10, "field_heat_score": 40, "bonus_score": 0, "brief_reason": "药物为anti-HER2 ADC，靶点HER2明确，ADC赛道热度较高。机构为医院/学术中心而非药企，无任何具体研发进展或摘要信息，导致里程碑和整体重要性评分很低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/364", "id": "LJ7ECZ0BZznHJdntvNYd", "source_drug_name": "anti-HER2 ADCs", "title": "Resistance to anti-HER2 ADCs", "abstract_text": "There is no abstract associated with this presentation.", "source_company": "Memorial Sloan Kettering Cancer Center", "source_org_type": "医院", "row_number": 330, "target_meta": "HER2", "MOA_meta": "抗体偶联药物"}, {"drug_name": "Antibody X", "company": "National University of Singapore", "org_type": "大学", "target": "未披露", "modality": "monoclonal antibody", "importance_level": "低", "total_score": 39.5, "institution_score": 35, "track_score": 55, "milestone_score": 30, "field_heat_score": 45, "bonus_score": 0, "brief_reason": "Antibody X为新型单抗，主要通过ADCC机制杀伤DLBCL细胞，但靶点未在摘要中明确披露。机构为大学非商业实体、仍处早期机制研究无明确开发里程碑，导致整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5168", "id": "OFXM_5wBX1NQZOEH-LG5", "source_drug_name": "Antibody X", "title": "Novel monoclonal antibody kills lymphoma cells via LFA-1/ICAM-1 dependent, antibody-mediated cellular cytotoxicity", "abstract_text": "Background: Diffuse large B-cell lymphoma (DLBCL) is an aggressive form of non-Hodgkin’s lymphoma. DLBCL patients undergo a first line immunochemotherapy regimen, termed R-CHOP. Unfortunately, approximately 40% of treated patients eventually relapse, or are non-responsive. Thus, there is an urgent need to devise new treatment options. Recently, a novel monoclonal antibody (Antibody X) has been developed as a potential therapeutic strategy.\nMethods: CD16 (Fc receptor)-expressing NK92 cells were used as effector cells against target DLCBL cell lines in co-culture assays. A high-content, high-throughput drug screening tool was developed to test the effects of small molecule drugs in combination with immunotherapies.\nResults: We observed that instead of direct cytotoxicity or complement-dependent cytotoxicity, Antibody X exerted its anti-tumour effect primarily through antibody-dependent cellular cytotoxicity (ADCC). To understand the regulators of Antibody X-mediated killing, we utilised a newly developed high-content, high-throughput drug screening tool to evaluate the effects of over 1000 FDA approved compounds on Antibody X-mediated ADCC of DLBCL cells. We noted that BCR-Abl inhibitors differentially regulated Antibody X-mediated ADCC through their effects on Src kinases. Cellular contact between lymphoma cells and immune effector cells was also disrupted through the blockade of LFA-1/ICAM-1 immunological synapse formation. This ultimately led to an absence of death in lymphoma cells.\nConclusion: Overall, findings from this study revealed that Antibody X-mediated ADCC is dependent on Src activity and LFA-1/ICAM-1 immunological synapses. We also demonstrated that the novel high-content, high-throughput ADCC platform can be used for immunotherapy-based combinatorial drug screens and mechanistic evaluation of ADCC.\n[E.K.C. and A.D.J. are co-corresponding authors for this work.]", "source_company": "National University of Singapore", "source_org_type": "大学", "row_number": 346, "target_meta": "not available", "MOA_meta": "单抗"}, {"drug_name": "KU44.71", "company": "Kingston University London", "org_type": "大学", "target": "integrin α6β4", "modality": "monoclonal antibody", "importance_level": "低", "total_score": 39.5, "institution_score": 25, "track_score": 60, "milestone_score": 35, "field_heat_score": 50, "bonus_score": 0, "brief_reason": "KU44.71为针对胰腺癌过表达的integrin α6β4的新型单抗，可内化但裸抗无增殖抑制作用，仅作为研究工具，潜在需人源化或ADC开发。机构为大学非商业研发、尚处早期表征阶段、无临床进展，赛道有一定热度但靶点非最热门导致总体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4331", "id": "TFXM_5wBX1NQZOEH-LG5", "source_drug_name": "KU44.71", "title": "Development and characterisation of a novel monoclonal antibody against overexpressed integrin α6β4 on human pancreatic cells", "abstract_text": "Despite major advances in the diagnosis and treatment of patients with cancer, pancreatic cancer remains one of the most aggressive and fatal cancer types. There is an urgent need for the discovery of additional therapeutic targets and the development of more effective therapeutics. Monoclonal antibody (mAb) technology is an excellent tool for the discovery of overexpressed cell surface tumour antigens, and antibodies generated may have significant diagnostic and therapeutic value. Here, we report the generation and characterisation of a novel antibody KU44.71 against the human ductal pancreatic adenocarcinoma metastasised to the liver cell line CFPAC-1, using hybridoma technology. Following screening, mAb KU44.71 which was directed against overexpressed cell surface antigens on pancreatic cancer cells was selected and purified by affinity chromatography. Further characterisation of the mAb was performed by ELISA, flow cytometry, cell proliferation assay, internalisation studies, immunoprecipitation and mass spectrometry, western blotting, and immunohistochemistry. We discovered that KU44.71 recognises the external domain of integrin α6β4 that is overexpressed by varying amounts in pancreatic cancer cell lines, derived from different sources including primary pancreatic cancer, liver metastasis, ascites and lymph node metastasis. Treatment with the naked antibody did not affect growth of α6β4 expressing pancreatic cancer cells. In contrast, exposure to anti-α6β4 KU44.71 induced internalisation of integrin α6β4 in pancreatic cancer cells. Furthermore, KU44.71 was found to be effective in detecting α6β4 expression by western blot and immunohistochemistry. Our results suggest that mAb KU44.71 is an useful tool for studying the role of α6β43 in the complex biology of human cancer, and for investigating the relative expression, prognostic significance, and predictive value of integrin α6β43 in patients with pancreatic cancer. Further studies are warranted to elucidate the therapeutic potential of this novel mAb including its humanised or drug conjugated versions in patients with α6β43 overexpressing pancreatic and other type of cancer.", "source_company": "Kingston University London", "source_org_type": "大学", "row_number": 362, "target_meta": "α6β4", "MOA_meta": "单抗"}, {"drug_name": "Ku-DBi 3392", "company": "Indiana University School of Medicine", "org_type": "大学", "target": "Ku70/80", "modality": "inhibitor", "importance_level": "低", "total_score": 39.5, "institution_score": 25, "track_score": 65, "milestone_score": 35, "field_heat_score": 50, "bonus_score": 0, "brief_reason": "Ku-DBi 3392为Ku70/80小分子抑制剂，与Osimertinib联用在EGFR突变NSCLC细胞系中显示增效作用，但仅为初步体外研究。机构为大学、开发阶段为preclinical早期且无明确临床推进信号导致总体评分较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4622", "id": "ZVXM_5wBX1NQZOEH-LG5", "source_drug_name": "Ku-DBi 3392", "title": "Targeting DNA damage sensors (DDS) to enhance Osimertinib response in EGFR-driven cancers", "abstract_text": "Lung cancer remains the leading cause of cancer-related mortality worldwide. Approximately 85% of cases are classified as non-small cell lung cancer (NSCLC) and activating mutations in the epidermal growth factor receptor (EGFR) are present in about 16% of metastatic NSCLC tumors. The development of EGFR tyrosine kinase inhibitors (EGFR-TKIs) including the third-generation agent Osimertinib, have significantly improved patient outcomes. Nonetheless, its efficacy is limited by both on-target and off-target resistance mechanisms, including the C797S mutation, MET amplification, and histological transformation. Emerging evidence has shown that EGFR signaling influences DNA repair, and that persistent proliferative signaling in EGFR-driven tumors elevates replication stress (RS), making them uniquely vulnerable to inhibition of the DNA damage response (DDR). While prior approaches have primarily targeted DDR kinases such as ATR, CHK1, and WEE1, the role of DNA damage sensors (DDS), including replication protein A (RPA) and the Ku70/80 complex, remains largely unexplored. In this study, we focus on this strategy by targeting RPA and Ku70/80, which recognize DNA structures generated by direct DNA damage or RS and initiate the DDR. Using small molecule inhibitors that target RPA and Ku-DNA binding in combination with clinically relevant EGFR-TKIs, we aimed to dissect the mechanistic interactions between DDR pathways and EGFR signaling to elucidate how DDR modulation impact therapeutic response and resistance in EGFR-driven NSCLCs. Our results show that the DDS inhibitors NERx-329 (RPAi) and Ku-DBi 3392 (Ku70/80) in combination with Osimertinib further enhances antiproliferative and cytotoxic effects in TKI-sensitive, EGFR-mutant NSCLC cells in an additive manner. Our data demonstrate that DDR inhibition is effective in TKI-sensitive EGFR-driven models potentiating Osimertinib activity. Importantly, this is independent of a DNA damaging agent, suggesting that inhibition of DDR itself is enough to increase the therapeutic effect of Osimertinib. This effect appears to be EGFR-specific, as no potentiation of Alectinib activity was observed in an EML4-ALK driven NSCLC model. These preliminary findings support a functional crosstalk between DDS-mediated DDR pathways and EGFR signaling highlighting a potential therapeutic strategy to overcome, delay, or prevent the recurrence of resistance in EGFR-driven NSCLC cancers.", "source_company": "Indiana University School of Medicine", "source_org_type": "大学", "row_number": 384, "target_meta": "XRCC6,XRCC5", "MOA_meta": "抑制剂"}, {"drug_name": "a novel carbazole-derived compound", "company": "University of Texas San Antonio", "org_type": "大学", "target": "Scaffold/Matrix Associated Regions (S/MARs)", "modality": "other", "importance_level": "低", "total_score": 39.5, "institution_score": 35, "track_score": 45, "milestone_score": 40, "field_heat_score": 50, "bonus_score": 3, "brief_reason": "该新型咔唑衍生物选择性靶向S/MARs区域，干扰染色质组织和DNA复制/修复相关基因表达，机制新颖但靶点非热门。大学早期研究，体外体内模型有效但仍处preclinical阶段，无明确临床里程碑，综合热度较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4359", "id": "klXM_5wBX1NQZOEH-LG6", "source_drug_name": "a novel carbazole-derived compound", "title": "Targeting scaffold/matrix associated regions in pancreatic ductal adenocarcinoma: A novel carbazole-derived therapeutic", "abstract_text": "Pancreatic cancer is the tenth most common cancer in the United States and is projected to become the second leading cause of cancer-related death by 2030. Most cases arise in exocrine cells and are driven by genetic mutations, such as KRAS and CDKN2A, as well as modifiable risk factors, including alcohol use, chronic pancreatitis, and obesity. The aggressive nature of pancreatic ductal adenocarcinoma (PDAC), coupled with its complex tumor microenvironment, leads to late-stage diagnoses and a five-year survival rate of 13%. Despite advances in treatment, which include surgical resection, radiotherapy, and chemotherapeutic regimens like gemcitabine and FOLFIRINOX, therapy-related toxicity and chemotherapy resistance remain significant barriers to improved outcomes. One promising therapeutic approach involves exploiting vulnerabilities in the DNA damage response (DDR) pathways unique to cancer cells. While cancer cells rely on an aberrant DDR to sustain unchecked replication, their increased mutational burden renders them particularly susceptible to DNA-targeting therapies. However, existing DNA-targeting treatments are limited by off-target effects, resulting in toxicity and the emergence of resistance. This underscores the need for novel, selective drugs capable of targeting DNA processes specific to cancer cells. We report on a novel carbazole-derived compound that represents a significant advancement in PDAC therapy. Carbazole, a nitrogen-containing heterocyclic molecule, serves as a pharmacophore in therapeutics with diverse applications, including antitumor, antiviral, and anti-inflammatory agents. Our compound demonstrates potent inhibition of PDAC growth and metastasis in both in vitro and in vivo models while sparing normal cells. Its mechanism of action involves selective targeting of Scaffold/Matrix Associated Regions (S/MARs), which play critical roles in chromatin organization and gene expression regulation. By disrupting S/MARs and their associated binding proteins, our compound downregulates essential genes involved in replication and DNA repair, including CDK4, MCMs, GINS, and CDC6. These findings suggest that our compound offers a unique therapeutic mechanism with high specificity and minimal toxicity. Furthermore, its potential to complement existing treatments and advance toward Investigational New Drug (IND) approval positions it as a promising candidate for PDAC therapy.", "source_company": "University of Texas San Antonio\nUT San Antonio", "source_org_type": "大学", "row_number": 407, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "anti-HER2 antibody", "company": "The George Washington University", "org_type": "大学", "target": "HER2", "modality": "antibody", "importance_level": "低", "total_score": 39.5, "institution_score": 25, "track_score": 65, "milestone_score": 30, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "药物为anti-HER2抗体，靶点HER2明确，但研究机构为大学，主要探讨抗生素扰乱肠道菌群导致HER2靶向治疗疗效下降的机制，而非药物自身开发或新候选药推进。机构非企业、研究处于机制探索阶段而无明显里程碑进展，导致总体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1300", "id": "OJ7ECZ0BZznHJdntvNYd", "source_drug_name": "anti-HER2 antibody", "title": "Antibiotic driven microbiota disruption impairs HER2 targeted therapy efficacy", "abstract_text": "Up to 60% of cancer patients require antibiotics during therapy, yet retrospective studies indicate that antibiotic exposure can worsen outcomes across cancers. In breast cancer (BC), HER2+ patients show notably reduced survival after antibiotic use, an effect attributed to microbiota disruption, though mechanisms remain unclear. Our previous work demonstrated the role of microbiota signaling in chemo and immunotherapy efficacy. But HER2+ BC relies on targeted therapies, thus the impact of antibiotics on these agents requires further investigation. To address this, we used 16S rRNA sequencing of cecal content from mice bearing HER2+ TUBO tumors to assess whether an anti-HER2 antibody or neratinib, a HER2 tyrosine kinase inhibitor, each induces distinct microbiota shifts. Anti-HER2 increased Oscillospiraceae, Rikenellaceae, Ruminococcaceae, and Lachnospiraceae, whereas neratinib increased only the latter two Families. However, alpha diversity metrics remained unchanged. To study how these microbes contribute to treatment, we first depleted the gut microbiota using a broad-spectrum antibiotic cocktail (ABX). We observed the partial and complete loss of anti-HER2 and neratinib efficacy, respectively, on TUBO tumors. A clinically relevant antibiotic, such as ciprofloxacin (cipro), also fully halted neratinib response, whereas amoxicillin/clavulanate (am/clav) caused partial impairment. Because both antibiotics and neratinib were administered orally, we quantified plasma neratinib by LC-MRM mass spectrometry and ruled out antibiotic-induced blockade of neratinib absorption. Cipro and am/clav significantly reduced alpha diversity to a lesser extent than ABX, with cipro showing the most dramatic effect. Families enriched by HER2 therapies, including Lachnospiraceae and Ruminococcaceae, were targeted by cipro and am/clav. Notably, both antibiotics increased Akkermansia, a Family previously linked to favorable immunotherapy outcomes, suggesting that HER2-targeted therapies may rely on microbiota features, like Lachnospiraceae or Ruminococcaceae, distinct from those supporting checkpoint blockade. Spectral flow cytometry analysis of the tumor immune infiltration revealed that HER2 therapies triggered NK, CD8+, and CD4+ T cell infiltration. Antibiotic-treated tumors showed enrichment of pro-tumor macrophages and neutrophils with no significant NK cell recruitment. Microbiota alpha diversity was positively correlated with tumor NK and CD8+ T cell content, which, in turn, were associated with treatment outcomes. Overall, our findings demonstrate that antibiotic-driven disruption of gut microbiota composition and diversity impairs immune mechanisms linked to the efficacy of HER2+ BC therapy. These results highlight the potential of microbiota-based strategies to mitigate antibiotic-associated therapeutic resistance in HER2+ BC.", "source_company": "The George Washington University\nGeorge Washington University", "source_org_type": "大学", "row_number": 414, "target_meta": "HER2", "MOA_meta": "抗体"}, {"drug_name": "anti-GAL1 antibody", "company": "Instituto de Biología y Medicina Experimental (IBYME-CONICET)", "org_type": "研究机构", "target": "GAL1", "modality": "antibody", "importance_level": "低", "total_score": 39.5, "institution_score": 35, "track_score": 55, "milestone_score": 25, "field_heat_score": 45, "bonus_score": 0, "brief_reason": "anti-GAL1 antibody针对胶质母细胞瘤中GAL1调控血管生成和代谢重编程的机制，但仅为研究机构开展的体外/前临床基础探索，缺乏明确临床开发进展。机构非药企、赛道非热门靶点/模态、开发阶段早期导致总体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1520", "id": "PZ7ECZ0BZznHJdntvNYd", "source_drug_name": "anti-GAL1 antibody", "title": "Galectin-1 as a central regulator of angiogenesis and metabolic reprogramming in glioblastoma", "abstract_text": "Glioblastoma (GB) is the most aggressive tumor of the central nervous system characterized by rapid growth and remarkable resistance to current therapies. Its biology is shaped by profound inter- and intra-tumoral heterogeneity, a highly immunosuppressive microenvironment, and a strong dependence on metabolic and vascular adaptations that allow tumor cells to thrive under hypoxic and nutrient-poor conditions. A subpopulation enriched in glioma stem-like cells (GSCs) plays a central role in these adaptations, sustaining tumor expansion through flexible metabolic and angiogenic programs. Galectin-1 (GAL1), a glycan-binding lectin with multiple roles in the tumor microenvironment, is considerably elevated in gliomas. This led us to investigate whether GAL1 could act as a common regulator of both metabolism and angiogenesis in GB. We established patient-derived GSC lines (G02, G03, G08, G09), a model that preserves the clinical heterogeneity typical of this disease. RNA-seq and functional assays revealed clear differences among cell lines. G02 showed an endothelial-like signature and promoted endothelial cell migration, while G03 was enriched in angiogenesis-related pathways and formed robust tube-like structures in vitro, in line with higher VEGF secretion (p<0.01). Biopsies from the corresponding patients (G02 and G03) recapitulated this biology, displaying broad areas of microvascular proliferation. Inhibition of GAL1 with antibodies or siRNA reduced tube formation mainly in G03, suggesting that not all angiogenic profiles are likely dependent on GAL1. Metabolic analysis further supported this idea. Seahorse analysis showed that G02 and G03 respond to GAL1 depletion by shifting toward opposite metabolic programs, and complementary assays (TMRE, MitoSOX) revealed high mitochondrial activity in G02 (FC=2), while G09 displayed impaired OXPHOS (FC=0.5). Together, our data indicate that both secreted and intracellular GAL1 contribute to the metabolic and angiogenic adaptations that sustain GB growth. These results emphasize that GSCs rely on distinct yet coordinated strategies to obtain resources, and position GAL1 as a central regulator of these processes. Defining the cellular and functional profiles that determine sensitivity to GAL1 inhibition may help guide the development of more precise anti-angiogenic or metabolic therapies for glioblastoma.", "source_company": "Instituto de Biología y Medicina Experimental (IBYME-CONICET)", "source_org_type": "研究机构", "row_number": 432, "target_meta": "not available", "MOA_meta": "抗体"}, {"drug_name": "monoclonal antibody targeted to HMGN3", "company": "University of Illinois College of Medicine", "org_type": "大学", "target": "HMGN3", "modality": "monoclonal antibody", "importance_level": "低", "total_score": 39.5, "institution_score": 35, "track_score": 55, "milestone_score": 25, "field_heat_score": 45, "bonus_score": 0, "brief_reason": "药物为靶向HMGN3的单抗，HMGN3在NEPC中高表达并促进肿瘤进展和转移，但靶点新颖性和临床验证尚处极早期。大学机构preclinical初步功能验证（抗体处理降低细胞活力），缺乏明确开发管线和强里程碑，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4663", "id": "QJ7ECZ0BZznHJdntvNYd", "source_drug_name": "monoclonal antibody targeted to HMGN3", "title": "Role of high mobility group nucleosome-binding domain-containing protein 3 (HMGN3) in prostate cancer progression a novel target for therapeutic intervention", "abstract_text": "Prostate cancer (PCa) accounts for more than one million new cases globally each year. Standard therapeutic approaches such as chemotherapy, radiotherapy, prostatectomy, and androgen deprivation therapy often yield only temporary benefits and are associated with substantial toxicity. Neuroendocrine prostate cancer (NEPC) represents a rare, highly aggressive subtype of PCa that may develop de novo or emerge as a treatment-resistant form of adenocarcinoma. NEPC is particularly challenging to manage because it is androgen receptor (AR) independent and responds poorly to conventional therapies. Chromatin modulators such as EZH2, BRD4, and NKX2-1 have been shown to promote the development of NEPC. One such novel chromatin regulator namely High Mobility Group Nucleosome-Binding Domain-Containing Protein 3 (HMGN3), a member of the HMGN protein family, binds nucleosomes and modulates chromatin structure, thereby influencing transcription, replication, and DNA repair may also have a role in the progression of NEPC. Previous research has demonstrated that HMGN3 promotes metastasis in cholangiocarcinoma by binding to the transcription factor SNAI2 and interacting with histone deacetylases (HDACs), leading to repression of epithelial-regulatory genes and induction of epithelial-mesenchymal transition (EMT). However, its role in PCa has not been previously explored. Bioinformatic analyses using PCA Tools and Betastasis indicate that AR-negative and neuroendocrine cell lines—such as NCI-H660 and LASCPC—exhibit the highest mRNA expression levels of HMGN3. This suggests that HMGN3 may contribute to EMT-associated metastatic pathways in PCa. To explore this, western blotting and RT-PCR were performed to analyze HMGN3 protein and mRNA levels in NEPC cell lines. Both NCI-H660 and LASCPC showed high protein expression, with LASCPC displaying the highest mRNA expression. Functional assays were carried out by treating BPH-1 cells with rHMGN3 in colony formation assays (CFA), while TRAMP-C1 cells were used for wound healing and Transwell migration assays. In these assays, treated groups demonstrated increased colony formation, accelerated wound closure, and higher migratory activity compared to controls. Additionally, a preliminary MTT cell viability assay performed in NCI-H660 cells treated with varying concentrations of monoclonal antibody targeted to HMGN3 showed reduced cell viability relative to untreated controls. Collectively, these findings suggest that HMGN3 as a significant enhancer of tumor growth and metastatic spread, being especially abundantly expressed in aggressive NEPC. In conclusion, our data supports that targeting HMGN3 could serve as an innovative therapeutic approach for advanced, treatment-resistant forms of PCa.", "source_company": "University of Illinois College of Medicine", "source_org_type": "大学", "row_number": 474, "target_meta": "HMGN3", "MOA_meta": "单抗"}, {"drug_name": "Taraxasterol", "company": "Zhengzhou University", "org_type": "大学", "target": "PTP1B", "modality": "other", "importance_level": "低", "total_score": 39.5, "institution_score": 25, "track_score": 45, "milestone_score": 55, "field_heat_score": 40, "bonus_score": 3, "brief_reason": "Taraxasterol靶向PTP1B抑制NF-κB通路，发挥抗H.pylori诱导胃炎及胃癌作用，但作为蒲公英来源天然小分子化合物。机构为大学非商业研发，开发阶段仅preclinical体外/体内模型，无临床进展，赛道非热门modality和靶点，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10812", "id": "P1XM_5wBX1NQZOEH-LK6", "source_drug_name": "Taraxasterol", "title": "Taraxasterol suppresses H. pylori-induced gastritis and gastric cancer by targetingPTP1B/PKM2/NF-κB signaling pathway", "abstract_text": "Chronic Helicobacter pylori infection is a primary cause of gastritis, peptic ulcers, and gastric cancer (GC), creating a demand for novel therapeutic agents that address both inflammation and tumor progression. Taraxasterol (TAX) has demonstrated significant therapeutic potential against both gastritis and gastric cancer (GC). In vitro, TAX effectively alleviated H. pylori-induced gastritis by reducing intracellular bacterial load and attenuating the inflammatory response, specifically by decreasing TNF-α levels and reactive oxygen species, and inhibiting the NF-κB signaling pathway (IKKα and P65 phosphorylation). TAX did not directly inhibit H. pylori growth, suggesting its mechanism is primarily anti-inflammatory. Beyond gastritis, TAX exhibited potent anti-cancer effects on GC cell lines (AGS and MGC803), dose-dependently inhibiting their proliferation and colony formation. Mechanistically, computational and experimental analyses (SPR, DARTS, CETSA) identified Protein Tyrosine Phosphatase 1B (PTP1B) as a direct target of TAX. PTP1B, found to be highly expressed in gastritis and GC tissues and associated with poor prognosis, had its phosphatase activity inhibited by TAX. Further studies showed that PTP1B knockdown inhibited GC cell proliferation and that TAX's anti-proliferative effects were partially mediated through PTP1B, modulating the PTP1B/PKM2/NF-κB signaling pathway. In vivo, TAX successfully inhibited H. pylori and/or alcohol-induced gastritis in mice, reducing inflammation, lymphocyte infiltration, and cytokine levels. Crucially, TAX also suppressed tumor growth in gastric cancer patient-derived xenograft (PDX) models. These findings collectively highlight TAX as a promising therapeutic agent for both gastritis and gastric cancer, primarily through its anti-inflammatory properties and its targeted inhibition of PTP1B.", "source_company": "Zhengzhou University", "source_org_type": "大学", "row_number": 525, "target_meta": "PTP1B", "MOA_meta": "其他"}, {"drug_name": "TXNRD(i)s", "company": "Loyola University Chicago", "org_type": "大学", "target": "TXNRD1/TXNRD2", "modality": "inhibitor", "importance_level": "低", "total_score": 39.5, "institution_score": 25, "track_score": 55, "milestone_score": 45, "field_heat_score": 50, "bonus_score": 2, "brief_reason": "新型非共价TXNRD1/2抑制剂针对TNBC显示DNA损伤和PARPi协同潜力，但研发机构为大学，处于早期研究阶段。打分较低主要因机构非商业化公司、项目仍为preclinical无临床进展。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4641", "id": "jVXM_5wBX1NQZOEH-LK6", "source_drug_name": "TXNRD(i)s", "title": "Expanding the therapeutic potential of TXNRD inhibitors for triple-negative breast cancer", "abstract_text": "Triple negative breast cancer (TNBC) has the lowest 5-year survival of all breast cancersubtypes, and for many patients the standard of care is limited to a multiagent chemotherapyregimen. Therefore, there is a need to explore improved therapeutic targets and strategies. We havepreviously demonstrated that elevated levels of both thioredoxin reductase 1 (TXNRD1) andthioredoxin reductase 2 (TXNRD2) correlates with lower recurrence-free and overall survival inTNBC and are both relevant targets for TNBC.We have developed new non-covalent TXNRD inhibitors (TXNRD(i)s) that successfullyinhibit TXNRD1 and TXNRD2 in TNBC models as demonstrated through fluorescent biochemicalassays and qPCR of TXNRD related genes. Additionally, these TXNRD(i)s show pleiotropic anti-cancer activity against aggressive phenotypes in both in vitro and in vivo TNBC models. Treatmentwith TXNRD(i)s reduces 2D viability, mammosphere formation, collagen invasion, and primaryxenograft growth in TNBC models.Mechanistically, we have identified ribonucleotide reductase (RNR) dysfunction causedby our TXNRD(i)s. Given that RNR provides dNTPs, the building block for both DNA synthesisand repair, this led to the hypothesis that TXNRD(i)s induce DNA damage and replicative stress.Furthermore, this is aggravated by poly (ADP-ribose) polymerase (PARP) inhibition, leading toa synergistic effect in BRCA wild-type TNBC cell lines. Using COMET and fork stall assays,microscopy, and western blotting, we concluded there is evidence of replicative stress and DNAdamage induced by our TXNRD(i)s and validated the inhibitors are acting on target by using agenetic approach with inducible TXNRD1 and TXNRD2 knockdowns of our model cell line.Using our TXNRD(i)s in combination with Olaparib, we observed synergistic effects with the twoinhibitors in BRCA wild-type TNBC models. The synergy shown between our TXNRD(i)s andPARP inhibitors in BRCA wild-type TNBC cell lines expands the therapeutic potential of ourTXNRD(i)s as well as opening the possibility to an expansion of PARP inhibitors.", "source_company": "Loyola University Chicago", "source_org_type": "大学", "row_number": 576, "target_meta": "TXNRD1,TXNRD2", "MOA_meta": "抑制剂"}, {"drug_name": "MEIS2i", "company": "Northwestern University", "org_type": "大学", "target": "MEIS2", "modality": "inhibitor", "importance_level": "低", "total_score": 39.5, "institution_score": 25, "track_score": 40, "milestone_score": 55, "field_heat_score": 45, "bonus_score": 0, "brief_reason": "MEIS2i为MEIS2转录因子的药理抑制剂，针对铂耐药卵巢癌癌干细胞特性显示体外和体内逆转耐药潜力。机构为大学、modality为普通小分子抑制剂、仅preclinical阶段导致整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8839", "id": "21XM_5wBX1NQZOEH-LK6", "source_drug_name": "MEIS2i", "title": "Targeting MEIS2 in platinum resistant ovarian cancer", "abstract_text": "Background: Recurrent ovarian cancer (OC) develops chemoresistance, which is fatal. Cancer stem cells (CSCs) have been hypothesized to be responsible for driving chemoresistance and tumor relapse. Myeloid Ecotropic Insertion Site 2 (MEIS) is a homeobox transcription factor (TF) that is deregulated in various cancers, playing critical roles in regulating stem cell identity and cell fate decisions. Here, I examined the role of MEIS2 in regulating stemness features that promote chemoresistance of OC, and the impact of a MEIS2 blockade on OC initiation and progression. ​\nMethods: Paired isogenic OC cell lines (platinum sensitive (Pt-S) and resistant (Pt-R)) were used. MEIS2 expression level in these cells was assessed by q-RT-PCR and Western Blotting. The effects of MEIS2 inhibition (by using a pharmacological inhibitor MEISi and biological knockdown (KD)) and overexpression (OE) on OC cell survival and chemosensitivity were assessed using colony formation and cell viability assay, and on stemness features by flow cytometry for analysis of ALDH+ CSC population and measurement of stemness-related gene expression. ​MEIS2 direct binding targets in OC cells were examined using ChIP-seq and validated using q-PCR. The anti-tumor effects of MEIS2 inhibition on Pt-R OC cells and tumor initiation were tested in vivo.\nResults: MEIS2 expression levels were increased in Pt-R vs. Pt-S OC cells at mRNA and protein levels. Treatment with MEIS2i (500nM-1µM) reduced the number of colonies in OC cells by at least 2-fold and resensitized Pt-R OC cells to cisplatin (p<0.05). Treatment with MEIS2i (250nM-1uM, 48 hours) decreased ALDH+ CSCs population by at least ~2-fold (p<0.05) and inhibited the expression of stemness-associated genes ALDH1 isoforms and Sox2 (p<0.05), compared to vehicle control. MEIS2 KD decreased the CSC population by two-fold (p<0.05) and inhibited stemness gene expression (p<0.05). By integrating ChIP-seq and RNA-seq, we identified that stemness-associated gene ALDH1A2 is a direct binding target of MEIS2 in OC cells, contributing to the maintenance of stemness and chemoresistant features. We further validated the MEIS2 binding region on the enhancer region of the ALDH1A2 genes using ChIP-qPCR, which is highly conserved across multiple species. In vivo, OC xenografts derived from MEIS2 KD OVCAR5 cells were more responsive to carboplatin (p<0.05) compared with control xenografts, and MEIS2 KD inhibited tumor-initiating capacity. Importantly, MEISi treatment alone (25μM/100μL, 5 days, 2 weeks) or in combination with carboplatin (25mg/kg, once/week, 2 weeks) suppressed OVCAR5 Pt-R xenograft tumor growth and inhibited ALDH+ CSC population in the tumor residuals.\nConclusions: Altogether, blocking MEIS2 in OC cells inhibits stemness traits that contribute to chemoresistance and tumor relapse, suggesting that MEIS2 is a potential new treatment target in OC therapy.", "source_company": "Northwestern University", "source_org_type": "大学", "row_number": 631, "target_meta": "MEIS2", "MOA_meta": "抑制剂"}, {"drug_name": "p53 siRNA and mRNA co-delivery LNP", "company": "Sungkyunkwan University", "org_type": "大学", "target": "p53", "modality": "other", "importance_level": "低", "total_score": 39.5, "institution_score": 30, "track_score": 75, "milestone_score": 20, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "药物通过靶向LNP共递送p53 siRNA和mRNA实现p53突变癌中p53的完全恢复，机制新颖但仅为大学preclinical概念验证，摘要被embargo无具体数据。机构为大学非产业化主体、开发阶段早期导致总体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11475", "id": "QVXM_5wBX1NQZOEH-LO6", "source_drug_name": "p53 siRNA and mRNA co-delivery LNP", "title": "Complete restoration of p53 in p53 mutant cancers through co-delivery of p53 siRNA and mRNA using a targeted LNP platform", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Sungkyunkwan University", "source_org_type": "大学", "row_number": 698, "target_meta": "p53", "MOA_meta": "其他"}, {"drug_name": "Spondweni virus", "company": "Nemours Children's Health", "org_type": "医院", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 39.5, "institution_score": 30, "track_score": 50, "milestone_score": 40, "field_heat_score": 45, "bonus_score": 0, "brief_reason": "Spondweni virus（黄病毒科）作为溶瘤病毒在子宫内膜癌细胞系中显示比Zika病毒更强感染和杀伤活性，但靶点机制未明确，仅为体外preclinical初步探索。机构为医院类型非药企、赛道溶瘤病毒非当前最热、开发阶段早期导致总分较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1482", "id": "_1XM_5wBX1NQZOEH-LO6", "source_drug_name": "Spondweni virus", "title": "Spondweni virus is highly oncolytic in endometrial carcinoma-derived HEC-1-A cells", "abstract_text": "Endometrial adenocarcinoma accounts for approximately 80% of all endometrial cancers, affecting more than 400,000 women per year. With advanced disease, the 5-year survival rate drops from 81% to 15%. Previously, our laboratory found that Zika virus (ZKV) has promising oncolytic and anti-tumor activities, reducing tumor volume in murine xenograft models of ovarian and endometrial cancer. Spondweni (SPN) is a flavivirus phylogenetically related to but immunologically distinct from ZKV. Like ZKV infection, most human SPN infections are asymptomatic. We hypothesized that SPN would exhibit oncolytic activity like that of ZKV. The endometrial adenocarcinoma cell line HEC-1-A, which was derived from a stage IA endometrial tumor, was selected for infection with three ZKV strains (MR766, ZIKV-A1, and ZIKV A-2) and one SPN strain (SPN A-1). Using viral plaque assays, AlamarBlue™ cell viability assays, and western blots, we examined viral replication in ZKV- and SPN-infected HEC-1-A cells, measuring NS-1 and viral envelope protein expression, and comparing rates of cell death following viral infection. Our data indicated that HEC-1-A cells are more susceptible to SPN than to ZKV. This discovery provides insight into SPN as an oncolytic therapy and opens the door to exploring its use in other cancer types.", "source_company": "Nemours Children's Health", "source_org_type": "医院", "row_number": 828, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "Rbin-2", "company": "Florida A&M University", "org_type": "大学", "target": "midasin (MDN1)", "modality": "inhibitor", "importance_level": "低", "total_score": 39.5, "institution_score": 25, "track_score": 45, "milestone_score": 45, "field_heat_score": 60, "bonus_score": 2, "brief_reason": "Rbin-2为midasin (MDN1)抑制剂，与ESR1突变协同促进内分泌耐药乳腺癌细胞侵袭和存活，联合elacestrant显示协同抑制作用。机构为大学、非热门靶点、仅体外preclinical阶段，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4865", "id": "E1XM_5wBX1NQZOEH-LS6", "source_drug_name": "Rbin-2", "title": "Cooperative role of ESR1 mutations and midasin in endocrine resistance and the therapeutic potential of dual targeting", "abstract_text": "While most cases of estrogen receptor-positive (ER+) breast cancer initially respond to endocrine therapy, inevitably many women acquire resistance. A major hurdle hampering the response of metastatic breast cancer patients to endocrine therapy is constitutively active point mutations in the ER ligand binding domain (LBD). We previously identified midasin (MDN1), a novel ribosomal protein, which was significantly overexpressed in MCF-7 endocrine-resistant breast cancer stem cells. Additional studies also indicated that midasin was required for growth, and stemness, but there was a mutation-dependent impact of midasin inhibition on mammosphere morphology and protein expression. However, the consequences of increased MDN1 expression and ESR1 mutations remain unclear. We hypothesize that ESR1 mutations along with dysregulated MDN1 cooperate to alter the microenvironment and position breast cancer cells for a survival advantage. The objective of this study was to elucidate the mechanism by which midasin inhibition alters the biology of breast cancer cells with ESR1 mutations. To address this, breast cancer patient tumor samples were queried using CPTAC, and MDN1 protein expression was significantly elevated in luminal, HER2+, and triple-negative tumors compared with normal breast tissue. In a metastatic breast cancer cohort (n = 379), 10% of patients exhibited alterations in MDN1, whereas 25% exhibited ESR1 alterations, primarily amplifications and missense mutations. A significant co-occurrence (log₂ OR = 1.60; q = 0.027) between these alterations suggested functional interplay between midasin and ER signaling. Molecular docking identified Rbin-2 as a compound interacting with midasin (docking score: –5.70). Proliferation assays using MCF-7 wild-type, MCF-7D538G, and MCF-7Y537S cells showed that 12 µM Rbin-2 produced ~50% growth inhibition. In 3D spheroid assays, Rbin-2 significantly decreased invasion, disrupted spheroid integrity, and promoted cell death, particularly in ER-mutant cells. Given these results and the clinical data, we examined co-targeting ER point mutations and midasin. Cells treated with 12 µM Rbin-2 plus 2.5–10 µM elacestrant exhibited ~79% growth inhibition. Combination Index analysis showed the strongest synergy in MCF-7Y537S and MCF-7D538G cells compared with the wildtype cells. Immunoblots demonstrated that elacestrant reduced ER and midasin expression, while the combination produced a synergistic decrease in MDN1, supporting a cooperative mechanism between ER signaling and midasin. Overall, our results indicate that aberrant ESR1 activity and elevated MDN1 cooperate to drive aggressive tumor phenotypes, and that simultaneous inhibition of ER and midasin may offer a novel therapeutic avenue for patients with ESR1-mutant, endocrine-resistant breast cancer.", "source_company": "Florida A&M University\nFlorida Agriculture and Mechanical University", "source_org_type": "大学", "row_number": 845, "target_meta": "MDN1", "MOA_meta": "抑制剂"}, {"drug_name": "anti-HER2 drug", "company": "Morehouse School of Medicine", "org_type": "大学", "target": "HER2", "modality": "inhibitor", "importance_level": "低", "total_score": 39.5, "institution_score": 25, "track_score": 60, "milestone_score": 40, "field_heat_score": 50, "bonus_score": 0, "brief_reason": "药物为针对HER2的抑制剂，在前列腺癌尤其是非裔患者中显示差异性敏感性，但仅为体外和基础研究，未披露具体新药。机构为大学，赛道HER2在乳腺外热度中等，开发阶段为preclinical，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3702", "id": "M1XM_5wBX1NQZOEH-LS6", "source_drug_name": "anti-HER2 drug", "title": "HER2 as a therapeutic target in prostate cancer: Multi-omic and spatial insights across genetic ancestries", "abstract_text": "INTRODUCTION: Patients with prostate cancer (PC) initially respond to androgen deprivation therapy. However, relapse is lethal. For this reason, inhibiting androgen-independent signaling pathways—such as human epidermal growth factor receptor 2 (HER2)—is a promising area of investigation. HER2 overexpression in PC tumors correlates with worse prognosis, but has not been sufficiently evaluated in Black men. We hypothesize that unique ancestry-associated multi-omic molecular signatures are modulated with anti-HER2 drug targeting.\nMETHODS: Using RNA sequencing, we quantified HER2/ERBB2 in primary patient tissue and correlated with quantified ancestry estimates. IHC staining was used to detect HER2 expression in primary prostate tissue. We quantified transcript and protein levels of HER levels in PC cell lines by qPCR and ELISA. CellTiter-Glo® assessed cell viability in PC cells treated with anti-HER2 drug. We performed multi-omic analyses using LC-tandem mass spectrometry and LC-PRM mass spectrometry. Biological pathway and network analysis was performed using Qiagen’s Ingenuity Pathway Analysis. We validated significantly modulated genes with qPCR. We performed immunofluorescence staining of HER2 and androgen receptor (AR) in treated vs. untreated PC cell lines. To resolve the spatial dynamics of ERBB2 and AR in ancestry genotyped patient-derived xenografts (PDXs), we utilized the 10x Genomics Xenium In Situ spatial transcriptomics platform.\nRESULTS: We detected moderate correlation with HER2/ERBB2 and West African genetic ancestry (WAA) in primary prostate tissue in a cohort of Black men (n=36). We detected HER2-positive scores in 70% of primary PC tissue in a separate cohort of Black men (n=10). Transcript and protein levels of HER2 were confirmed in PC cells. We observed significantly reduced viability only in HER2-targeted PC cells from Black patients. Systems biology revealed differential pathway and network expression in HER2-targeted PC cells derived from Black men compared with white men. Common significantly modulated genes ERBB2, MYC, MYCN, and TP63 were validated. HER2 and AR immunofluorescence staining diminished with HER2 drug targeting. Spatial transcriptomic analysis revealed that the ERBB2 and AR transcript burden per tumor area were significantly higher in a PDX developed from a Black patient (58% WAA) compared to a PDX developed from a white patient (0% WAA).\nCONCLUSIONS: Thorough evaluation of the molecular mechanisms by which HER2 overexpression confers tumor progression and treatment-resistance will provide the foundation to address high-risk PC with precision medicine. By leveraging the unique characteristics of HER2-positive tumors, an additional oncogenic pathway can be therapeutically targeted which will have a major impact in reducing progression to metastasis and reducing mortality.", "source_company": "Morehouse School of Medicine", "source_org_type": "大学", "row_number": 869, "target_meta": "HER2", "MOA_meta": "抑制剂"}, {"drug_name": "folate-conjugated copolymer", "company": "California Comprehensive Allergy and Food Institute, P.C.", "org_type": "公司", "target": "YAP/TAZ-HIPPO oncoproteins", "modality": "other", "importance_level": "低", "total_score": 39.5, "institution_score": 20, "track_score": 75, "milestone_score": 30, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "药物通过叶酸偶联共聚物靶向抑制YAP/TAZ-HIPPO通路，针对胰腺癌进展和转移，具有新机制亮点。机构为小型专业研究所，非主流药企导致机构分低，摘要未公开且无明确开发阶段信息致里程碑分低，总分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11296", "id": "ilXM_5wBX1NQZOEH-LS6", "source_drug_name": "folate-conjugated copolymer", "title": "Cutting-edge, drug-free targeted cancer therapeutic: Smart folate-conjugated copolymer intrinsically disables the YAP/TAZ-HIPPO oncoproteins and abrogates pancreatic cancer progression and metastasis", "abstract_text": "Abstract is embargoed at this time.", "source_company": "California Comprehensive Allergy and Food Institute, P.C.", "source_org_type": "公司", "row_number": 931, "target_meta": "YAP/TAZ", "MOA_meta": "其他"}, {"drug_name": "siR-2-6", "company": "Gifu Univ. Hospital", "org_type": "医院", "target": "PTBP1", "modality": "siRNA", "importance_level": "低", "total_score": 39.5, "institution_score": 25, "track_score": 65, "milestone_score": 35, "field_heat_score": 45, "bonus_score": 2, "brief_reason": "siR-2-6为化学修饰的siRNA靶向PTBP1，通过调控PKM1/PKM2剪接逆转Warburg效应诱导肿瘤细胞凋亡。机构为大学医院、仍处早期preclinical优化阶段、代谢重编程赛道有一定新颖性但整体热度和里程碑价值有限。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10415", "id": "llXM_5wBX1NQZOEH-LS6", "source_drug_name": "siR-2-6", "title": "Preclinical study of nucleic acid therapeutics targeting the Warburg effect", "abstract_text": "[Background] Cancer cells rely on glycolysis for energy, known as the Warburg effect, which supports survival by promoting nucleotide synthesis, reducing oxidative stress, and inhibiting cell death.\nPolypyrimidine tract-binding protein 1 (PTBP1) regulates pyruvate kinase muscle (PKM1/PKM2) splicing, maintaining a PKM2-dominant state. Suppressing PTBP1 shifts cellular metabolism to a PKM1-dominant state, reduces glycolysis, alters ATP production, and increases oxidative stress, ultimately resulting in cell death.\nWe developed optimized chemically modified siR-PTBP1 derivatives to evaluate their therapeutic potential.\n[Methods] Anti-proliferative activity in human colorectal DLD-1 cells was tested by chemically modified siR-PTBP1 derivatives. Cell viability was assessed by CVS assay, and PTBP1, PKM1/PKM2, and cleaved PARP protein levels were analyzed by Western blotting and immunostaining after the transfection. ATP production and oxidative stress assay were performed to examine the alternation from glycolysis-dominant to oxidative phosphorylation via TCA cycle. Metabolome analysis was also examined.\n[Results] Among 14 derivatives, the derivative siR-2-6 significantly suppressed PTBP1, increased PKM1 expression, and raised the PKM1/PKM2 ratio. Increased cleaved PARP expression indicated apoptosis induction and Warburg effect suppression. Also, siR-2-6 increased ATP production and oxidative stress, resulting in apoptosis. The higher RNase resistance and biological activity under RNase-containing conditions were shown in comparison to those of the SiR-2-1 that is not chemically modified.\n[Conclusion] Optimized siR-PTBP1 derivatives increased the PKM1/PKM2 ratio and partially shifted cellular metabolism from glycolysis dependence to oxidative phosphorylation, highlighting their potential as nucleic acid therapeutics.\nThe enhanced RNase resistance of siR-2-6 further supports its promise for in vivo application and clinical translation.", "source_company": "Gifu Univ. Hospital", "source_org_type": "医院", "row_number": 940, "target_meta": "PTBP1", "MOA_meta": "其他"}, {"drug_name": "BBM-loaded BSA nanoparticles", "company": "China Medical University", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 39.5, "institution_score": 25, "track_score": 45, "milestone_score": 50, "field_heat_score": 40, "bonus_score": 0, "brief_reason": "BBM为天然小分子化合物，通过BSA纳米粒递送增强抗CRC凋亡作用，但靶点机制未明确披露。机构为大学、处于preclinical阶段且非热门modality/靶点导致整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6409", "id": "gJ7ECZ0BZznHJdntvNYd", "source_drug_name": "BBM-loaded BSA nanoparticles", "title": "Enhanced antitumor efficacy of berbamine dihydrochloride nanomedicine via apoptosis induction in colorectal cancer", "abstract_text": "Background: Berbamine dihydrochloride (BBM), a natural bisbenzylisoquinoline alkaloid, exhibits broad antitumor activity. However, its clinical translation is hampered by nonspecific tissue distribution, poor bioavailability, and dose-limiting toxicity. Bovine serum albumin (BSA) nanoparticles represent an ideal drug delivery platform because of their biocompatibility, low immunogenicity, and inherent tumor-targeting capability. This study aimed to develop BBM-loaded BSA nanoparticles (BBM-BSA-NPs) to enhance drug targeting and antitumor efficacy against colorectal cancer (CRC).\nMethods: BBM-BSA-NPs were prepared and characterized. In vitro cytotoxicity was assessed against CRC cell lines (CT26, HT29) and other cancer lines (AGS, CAOV3, HepG2) via CCK-8 assays. Selectivity was evaluated by comparing the effects on cancer cells with those on normal 293 cells. Apoptosis induction was measured by flow cytometry. In vivo antitumor efficacy and systemic safety were investigated in a murine CT26 tumor model.\nResults: Compared with native BBM, BBM-BSA-NPs significantly increased the cytotoxicity to CT26 and HT29 cells in a concentration- and time-dependent manner (P < 0.05). The formulation showed selective toxicity toward cancer cells, with markedly greater inhibition in HepG2 cells (P < 0.05) and minimal effects on normal 293 cells at 24 h and 48 h. Notably, BBM-BSA-NPs effectively induced morphological changes and apoptosis in CT26 cells, with apoptosis rates significantly exceeding those of native BBM at all concentrations tested (P < 0.05). In vivo, BBM-BSA-NP treatment resulted in a remarkable reduction in tumor volume (279.19 ± 46.75 mm³) and weight (0.13 ± 0.04 g), significantly outperforming native BBM (456.75 ± 54.64 mm³; 0.29 ± 0.04 g; P < 0.05). No significant changes in body weight or systemic toxicity were observed, confirming the safety of the treatment. The blank BSA-NPs showed no antitumor activity, confirming that the efficacy and safety benefits were attributable to the nanoformulation.\nConclusion: We successfully developed a novel BBM-BSA nanoparticle system that significantly enhances the selective cytotoxicity and apoptotic induction of BBM against colorectal cancer while improving its therapeutic efficacy in vivo. This study provides a compelling rationale for leveraging albumin nanoparticles to repurpose BBM as a potent and safe therapeutic agent for CRC.", "source_company": "China Medical University", "source_org_type": "大学", "row_number": 1000, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "JNK-IN-8", "company": "University of Hawai'i Cancer Center", "org_type": "研究机构", "target": "JNK (pan-JNK)", "modality": "inhibitor", "importance_level": "低", "total_score": 39.5, "institution_score": 25, "track_score": 60, "milestone_score": 35, "field_heat_score": 50, "bonus_score": 0, "brief_reason": "JNK-IN-8为pan-JNK抑制剂，摘要显示其在TNBC模型中抑制肿瘤生长并重塑免疫微环境，但仅为工具化合物性质的preclinical研究。机构为大学癌症中心、开发阶段早期且无明确临床转化迹象导致总体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10550", "id": "T57M_5wBZznHJdnt_W3O", "source_drug_name": "JNK-IN-8", "title": "Dual roles of JNK1 and JNK2 in TNBC progression and tumor microenvironment immune modulation reveal a novel therapeutic vulnerability", "abstract_text": "Background: Triple-negative breast cancer (TNBC), one of the most lethal breast cancer subtypes, is driven by hyperactive oncogenic pathways that promote tumor growth and suppress antitumor immunity. Aberrantly high c-Jun N-terminal kinase (JNK) signaling is emerging as a key driver of tumor progression and immune evasion; however, the distinct roles of JNK1 and JNK2 in TNBC are largely undefined. This knowledge gap constrains efforts to exploit JNK biology for therapeutic advancement. Here, we investigated how each isoform drives tumor-intrinsic behavior and remodels the tumor microenvironment (TME). We hypothesized that both JNK1 and JNK2 drive TNBC growth and promote an immunosuppressive TME, and that loss of either isoform reprograms the TME toward a more immune-permissive, antitumor state. Methods: The impact of JNK signaling inhibition on PyMT-N TNBC cell growth was evaluated pharmacologically, using the pan-JNK inhibitor JNK-IN-8, and genetically, by knocking out JNK using the CRISPR-Cas9 system. Cell growth was evaluated using CellTiter-Blue viability and clonogenic assays. Immunocompetent syngeneic C57BL/6 mice bearing JNK1-, JNK2-, or dual-knockout (KO) tumors were used to assess tumor-intrinsic roles of each isoform; in parallel, jnk1-/- and jnk2-/- C57BL/6 mice bearing JNK-KO tumors were used to distinguish host-dependent effects. Immune cell tumor infiltration was quantified by flow cytometry. Cytokines were profiled by cytokine arrays and validated by ELISA and qPCR.Results: JNK-IN-8 (5 μm) suppressed PyMT-N cell growth by 85.1%, while KO of JNK1, JNK2, or both reduced colony formation by 55.3%, 67.7%, and 42.0%, respectively. Intratumoral JNK1 or JNK2 KO reduced tumor growth by 44.2% and 53.4%, respectively, and dual KO produced the most profound effect. These results highlight the strong tumor-intrinsic dependence of TNBC on both isoforms. Compared with Cas9 controls, JNK1-KO and JNK2-KO tumors exhibited increases in activated CD8⁺ T cells (83.4% and 53.3%, respectively) and reductions in Tregs (37.9% and 24.9%, respectively), indicating a shift toward an immunoactive TME. Furthermore, JNK1-KO and JNK2-KO tumors showed reduced TSLP expression and increased IGF-1 expression, suggesting JNK’s regulation of these cytokines. In host-dependent studies using jnk1-/- and jnk2-/- C57BL/6 mice, loss of either isoform reduced tumor growth, though to a lesser degree than intratumoral KO. Host JNK1 deficiency increased M1 macrophages and NK cells, while JNK2 deficiency increased CD8⁺ T cells and NK cells; both showed reduced Tregs, indicating the induction of an immunoactive TME.Conclusion: Both intratumoral JNK1 and JNK2 are critical drivers of TNBC growth and TME immunosuppression, and their loss reprograms the TME toward robust antitumor immunity, positioning JNK signaling as a compelling therapeutic target in TNBC.", "source_company": "University of Hawai'i Cancer Center", "source_org_type": "研究机构", "row_number": 1002, "target_meta": "JNK", "MOA_meta": "抑制剂"}, {"drug_name": "fibrates", "company": "Duke University", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 39.5, "institution_score": 30, "track_score": 40, "milestone_score": 50, "field_heat_score": 45, "bonus_score": 0, "brief_reason": "fibrates为脂质调节药物，在摘要中用于逆转ascites诱导的铁死亡保护机制并抑制卵巢癌小鼠模型腹膜播散，但未披露明确靶点。大学机构+preclinical工具化合物性质+铁死亡领域新兴但非热门赛道导致整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1539", "id": "VZ7M_5wBZznHJdnt_W3O", "source_drug_name": "fibrates", "title": "Ascites protects against ferroptosis and enables the peritoneal spread of ovarian cancer", "abstract_text": "One of the most common sites of metastasis in ovarian cancer (OVCA) is the peritoneum. Often, this spread is accompanied by the accumulation of a fluid called ascites in the peritoneal cavity. Despite its common occurrence in metastatic OVCA patients, ascites and its influence on the peritoneal spread of OVCA are poorly understood. Interestingly, OVCA cells are vulnerable to ferroptosis, a type of cell death caused by lipid hydroperoxides. Hence, how these ferroptosis-sensitive OVCA cells persist in their spread to the peritoneum remains unknown. Here, we show that ascites robustly protects OVCA cell lines, patient-derived tumor cells and organoids against ferroptosis and enhances the peritoneal spread of OVCA cells in mice. Mechanistically, ascites downregulates the mitochondrial enzyme, 3-hydroxy-3-methylglutaryl-CoA synthase 2 (HMGCS2), which contributes to an increase in lipid droplets. Additionally, upon ferroptosis induction, ascites represses the upregulation of the transferrin receptor, TFRC, thereby decreasing cellular labile iron levels. Furthermore, we show that lipid-lowering fibrates reverse cellular changes induced by ascites, and they attenuate the peritoneal spread of OVCA cells in mice. Our findings implicate the importance of ascites in ferroptosis protection and the peritoneal spread of OVCA, and they suggest that targeting the ferroptosis protection by ascites may present a novel therapeutic approach to limit OVCA metastasis.", "source_company": "Duke University", "source_org_type": "大学", "row_number": 1008, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "multireceptor tyrosine kinase inhibitors", "company": "Nationwide Children's Hospital", "org_type": "医院", "target": "未披露", "modality": "inhibitor", "importance_level": "低", "total_score": 39.5, "institution_score": 25, "track_score": 60, "milestone_score": 35, "field_heat_score": 45, "bonus_score": 0, "brief_reason": "药品为多靶点酪氨酸激酶抑制剂（TKIs），靶点未具体披露，仅泛指可匹配激酶通路。机构为医院/研究型，赛道为经典小分子抑制剂但转移微环境方向有一定新意，整体处于概念验证早期阶段，无明确临床里程碑。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5945", "id": "ZJ7M_5wBZznHJdnt_W3O", "source_drug_name": "multireceptor tyrosine kinase inhibitors", "title": "Identifying vulnerabilities through an elucidation of the tumor-host interplay that drives osteosarcoma lung colonization", "abstract_text": "Metastasis is the single most critical determinant of outcome in many solid tumors. In pediatric osteosarcoma, the development of lung metastases is associated with more aggressive and treatment-resistant tumor behavior. While many have assumed that metastasis is a consequence of this more aggressive behavior, emerging evidence suggests that interactions driving colonization reshape the behavior of both tumor and stromal compartments, reinforcing the resilience of metastatic lesions.\nOur recent work has shown that colonization induces changes in lung epithelial cells, infiltrating macrophages, and tumor cells, forming a microenvironment dominated by a dense, scar-like matrix that promotes tumor survival and proliferation. While we have shown that this aberrant niche can be disrupted by several multireceptor tyrosine kinase inhibitors (TKIs), each agent appears to affect lesions through distinct mechanisms. Identifying the specific pathways responsible for these anti-tumor effects has proved challenging.\nTo address this, we developed an algorithm that identifies aberrantly activated, kinase-dependent signaling pathways within each individual cell type. This approach revealed that several distinct, self-reinforcing microenvironments can emerge during lung colonization, and that each of these emergent networks activates a characteristic subset of kinase-dependent pathways. Importantly, these pathway signatures can be matched against the known activity profiles of available TKIs to predict which agents may be most effective for a given tumor.\nTo improve the effectiveness of this algorithm, we refined this predictive process by using CROP-seq to generate a purpose-built database for the accurate identification of kinase-driven transcriptional programs within each relevant cell type. The incorporation of spatial transcriptomics further refines predictions by resolving cellular neighborhoods to identify the most meaningful interactions occurring within a metastatic lesion.\nThrough this process, we aim to make every patient an exceptional responder by elucidating the targetable pathways driving the formation and maintenance of individual metastatic lesions and matching these vulnerabilities to the most effective available drug.", "source_company": "Nationwide Children's Hospital", "source_org_type": "医院", "row_number": 1018, "target_meta": "not available", "MOA_meta": "抑制剂"}, {"drug_name": "nanobody", "company": "Houston Methodist Research Institute", "org_type": "研究机构", "target": "未披露", "modality": "nanobody", "importance_level": "低", "total_score": 39.5, "institution_score": 30, "track_score": 75, "milestone_score": 20, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "纳米抗体（nanobody）用于优化药代动力学和连接子化学以提升靶向放射治疗疗效，但靶点未披露，摘要仍处于禁运状态。机构为研究机构非头部药企，开发阶段仅标题暗示preclinical优化，无明确里程碑，赛道为热门的nanobody+靶向放疗但缺乏具体信息导致总体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11491", "id": "xJ7M_5wBZznHJdnt_W3O", "source_drug_name": "nanobody", "title": "Rational engineering of nanobody pharmacokinetics and linker chemistry to maximize targeted radiotherapy efficacy", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Houston Methodist Research Institute", "source_org_type": "研究机构", "row_number": 1091, "target_meta": "not available", "MOA_meta": "单域抗体"}, {"drug_name": "plasmid encoding the extracellular domain of the PD1 protein", "company": "USF Health Morsani College of Medicine", "org_type": "大学", "target": "PD-1/PD-L1", "modality": "other", "importance_level": "低", "total_score": 39.5, "institution_score": 25, "track_score": 60, "milestone_score": 45, "field_heat_score": 50, "bonus_score": 2, "brief_reason": "该plasmid表达PD1胞外域作为可溶性PD-1蛋白阻断PD-1/PD-L1通路，属于基因递送形式的免疫检查点抑制策略；大学机构研发处于早期动物模型验证阶段，缺乏临床转化迹象，综合重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5577", "id": "157M_5wBZznHJdnt_W3O", "source_drug_name": "plasmid encoding the extracellular domain of the PD1 protein", "title": "Intellipulse platform for efficient and effective delivery of therapeutics to solid tumors", "abstract_text": "The Intellipulse® system is a next generation user-friendly platform for safe and controlled delivery of therapeutics to solid tumors. One issue with delivering therapeutics is being able to get the agent where it is needed without unwanted adverse effects related to clearance of a carrier or off-target events. The second issue with any nucleic acid delivery is having confidence that delivery has occurred. We have demonstrated the utility of this platform by delivering two plasmids encoding immune modifiers directly to melanoma tumors to induce a robust immune response. We previously demonstrated that the intratumor delivery of a plasmid encoding interleukin-12 (pIL-12) resulted in a significant increase in T effector cells and a reduction in T regulatory cells and myeloid derived suppressor cells within the TME, inducing a robust systemic immune response that was amplified when combined with ICIs. The key to make this an effective therapy is to deliver these agents in a manner that has minimal adverse and off target effects while still inducing the desired response. We have designed a novel approach to efficiently deliver multiple plasmids directly to solid tumors. The rationale was based on the premise that by performing intratumor delivery, stimulation would be directed against the specific antigens within the TME to produce an effective local response while stimulating a systemic response, resulting in an abscopal effect. This delivery utilizes a next generation electrotransfer device that enables the use of significantly reduced voltages and includes a means to monitor when successful delivery has occurred. We tested this concept in the B16.F10 mouse melanoma model. Intratumor delivery of pIL-12 resulted in effective control of the treated tumor in over 90% of the mice and generated resistance to challenge. To fully test this approach, we next evaluated a combination therapy delivering both pIL-12 combined with a plasmid encoding the extracellular domain of the PD1 protein, as an alternative form of checkpoint inhibitor. The therapy was tested in a multi-tumor model which included a subcutaneous tumor and intraperitoneal injection of tumor cells. The plasmids were delivered to the subcutaneous tumor; tumors generated by intraperitoneal injection were untreated. Peritoneal tumor growth was not affected by single plasmid delivery or when both plasmids were delivered using other delivery approaches or older electrotransfer technology. Delivery of the plasmids with the Intellipulse® platform resulted in two significant results. Binding of the expressed PD1 peptide to PDL1 on tumor cells was observed by immunohistochemistry and flow cytometry. In addition, complete regression in 90% of the treated mice of the subcutaneous tumor and blockage of peritoneal tumor growth as assessed via in vivo imaging was observed. Work is continuing to explore the treatment of other tumor types.", "source_company": "USF Health Morsani College of Medicine", "source_org_type": "大学", "row_number": 1105, "target_meta": "PD1/PDL", "MOA_meta": "其他"}, {"drug_name": "P-selectin-targeted nanomedicine", "company": "Tel Aviv University", "org_type": "大学", "target": "P-selectin", "modality": "nanomedicine", "importance_level": "低", "total_score": 39.5, "institution_score": 30, "track_score": 75, "milestone_score": 20, "field_heat_score": 60, "bonus_score": 3, "brief_reason": "该纳米药物靶向P-selectin以促进跨越血脑屏障、增强GD2-CAR T疗效，属于纳米递送系统辅助细胞治疗的创新策略。机构为大学非商业研发、摘要仍处于embargo缺乏具体数据、开发阶段不明导致整体评分较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11365", "id": "Z57M_5wBZznHJdnt_W7P", "source_drug_name": "P-selectin-targeted nanomedicine", "title": "Overcoming the blood-brain barrier to potentiate GD2-CAR T therapy using P-selectin-targeted nanomedicine", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Tel Aviv University", "source_org_type": "大学", "row_number": 1192, "target_meta": "SELP", "MOA_meta": "其他"}, {"drug_name": "Pseudoginsenoside F11", "company": "Nankai University", "org_type": "大学", "target": "YBX1", "modality": "other", "importance_level": "低", "total_score": 39, "institution_score": 30, "track_score": 40, "milestone_score": 50, "field_heat_score": 50, "bonus_score": 3, "brief_reason": "PF11通过直接结合转录因子YBX1增强其对PRPS2启动子的抑制，招募NuRD复合物实现转录抑制，从而降低TNBC干性和肺转移。机构为大学非商业研发、preclinical阶段无明确临床推进、天然小分子赛道非热门导致总体分值较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8846", "id": "G1XM_5wBX1NQZOEH-LG5", "source_drug_name": "Pseudoginsenoside F11", "title": "Pseudoginsenoside F11 enhances YBX1-mediated transcriptional repression of PRPS2 to inhibit the stemness and pulmonary metastasis of triple negative breast cancer", "abstract_text": "Background: Hyperactive de novo nucleotide synthesis is a metabolic hallmark of pulmonary metastatic triple-negative breast cancer (TNBC), largely driven by the upregulation of phosphoribosyl pyrophosphate synthetase 2 (PRPS2). The absence of specific PRPS2 inhibitors represents a significant unmet therapeutic need for preventing TNBC metastasis.Methods: We screened a library of 320 traditional Chinese herb-derived compounds using a PRPS2-promoter-driven luciferase reporter assay in TNBC cells. The lead compound was evaluated in vitro for effects on PRPS2 expression and cancer stemness, and in vivo using a murine pulmonary metastasis model. The direct target of PF11 was identified via biotin-conjugated pull-down assays. Mechanistic insights were gained through chromatin immunoprecipitation (ChIP) and reporter assays.Results: Pseudoginsenoside F11 (PF11) was identified as a potent inhibitor of PRPS2 transcription. Treatment with PF11 significantly suppressed PRPS2 expression, cancer cell stemness, and pulmonary metastasis in murine models. We identified the transcription factor YBX1 as the direct binding target of PF11. PF11 binding enhanced YBX1's affinity with the PRPS2 promoter, enabling it to compete with and displace the transcriptional activator c-Myc. Subsequently, YBX1 recruited the NuRD corepressor complex to the promoter, leading to transcriptional repression of PRPS2.Conclusion: Our findings unveil a novel mechanism by which PF11 activates a YBX1-NuRD corepressor complex to downregulate PRPS2, thereby attenuating TNBC stemness and metastasis. We propose PRPS2 as a druggable target and PF11 as a promising natural compound for the targeted therapy of TNBC.", "source_company": "Nankai University", "source_org_type": "大学", "row_number": 328, "target_meta": "YBX1", "MOA_meta": "其他"}, {"drug_name": "B3", "company": "Sungkyunkwan University", "org_type": "大学", "target": "KDM4B", "modality": "inhibitor", "importance_level": "低", "total_score": 39, "institution_score": 25, "track_score": 55, "milestone_score": 35, "field_heat_score": 45, "bonus_score": 0, "brief_reason": "B3为KDM4B选择性抑制剂，在体外模型中显示抑制乳腺癌细胞（包括他莫昔芬耐药株）增殖及代谢重编程的潜力。机构为大学、仍处于早期工具化合物阶段、缺乏临床转化迹象导致整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/2108", "id": "QlXM_5wBX1NQZOEH-LG5", "source_drug_name": "B3", "title": "Epigenetic regulation of histone lysine demethylase 4B on cancer therapy in tamoxifen-sensitive and -resistant breast cancer cells", "abstract_text": "Background: Histone lysine demethylase 4B (KDM4B), a key histone lysine demethylase, is aberrantly overexpressed in breast cancer and functions as an essential epigenetic co-activator of ERα signaling. Although its oncogenic role in breast tumorigenesis has been established, the functional distinctions and underlying molecular mechanisms of KDM4B in tamoxifen-sensitive versus tamoxifen-resistant states remain poorly defined. Elucidating KDM4B’s contribution to the evolution of endocrine resistance will be critical for identifying novel therapeutic targets and advancing precision strategies to overcome resistance to endocrine therapy.\nMethods: KDM4B expression across human cancers and normal tissues was evaluated using TCGA and GTEx datasets. To investigate its functional role, we compared the effects of KDM4B modulation in ERα-positive MCF-7 cells and their tamoxifen-resistant derivative, MCF-7 TamR. KDM4B was suppressed either by siRNA-mediated knockdown or by pharmacological inhibition using the selective KDM4B inhibitor B3. Cell proliferation was measured through MTT and colony formation assays. Protein expression levels of ERα, Bcl-2, H3K9me3, Cyclin D1, c-Myc, and related signaling molecules were examined via Western blotting. Cell-cycle progression and apoptosis were analyzed using flow cytometry. Metabolic reprogramming was evaluated using the Seahorse glycolytic stress test.\nResults: TCGA and GTEx analyses revealed that KDM4B is significantly overexpressed in breast cancer compared with normal breast tissue. Consistently, KDM4B levels were markedly elevated in tamoxifen-resistant MCF-7 (TamR) cells relative to parental MCF-7 cells. Suppression of KDM4B through siRNA-mediated knockdown or pharmacological inhibition substantially reduced the proliferative capacity and colony-forming ability of both MCF-7 and TamR cells. KDM4B depletion restored H3K9me3 enrichment, decreased ERα expression, and induced G1/S cell-cycle arrest. In addition, metabolic profiling demonstrated that KDM4B inhibition attenuated glycolytic activity, indicating a role in metabolic reprogramming.\nConclusion: KDM4B serves as a critical epigenetic regulator in both tamoxifen-sensitive and tamoxifen-resistant ERα-positive breast cancer. Inhibition of KDM4B restores repressive histone marks, suppresses ERα-dependent transcription, and attenuates cellular proliferation and metabolic activity. The heightened dependence of tamoxifen-resistant cells on KDM4B further underscores its potential as a promising therapeutic target for overcoming endocrine therapy resistance.", "source_company": "Sungkyunkwan University", "source_org_type": "大学", "row_number": 355, "target_meta": "KDM4B", "MOA_meta": "抑制剂"}, {"drug_name": "immunostimulatory RLT", "company": "University of Pittsburgh", "org_type": "大学", "target": "未披露", "modality": "RLT imaging agent", "importance_level": "低", "total_score": 39, "institution_score": 30, "track_score": 70, "milestone_score": 20, "field_heat_score": 50, "bonus_score": 0, "brief_reason": "药物为免疫刺激型放射配体治疗（RLT），靶点未在摘要中披露，仅为会议标题，无具体机制或数据。因机构为大学而非商业公司，开发阶段仅标题暗示preclinical概念，缺乏实质进展，导致总分较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/286", "id": "tFXM_5wBX1NQZOEH-LG6", "source_drug_name": "immunostimulatory RLT", "title": "Development of immunostimulatory RLT to enhance efficacy of immunotherapeutic regimens", "abstract_text": "There is no abstract associated with this presentation.", "source_company": "University of Pittsburgh", "source_org_type": "大学", "row_number": 439, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "L19-AuNP", "company": "Nano Flow", "org_type": "company", "target": "FN-EDB", "modality": "other", "importance_level": "低", "total_score": 39, "institution_score": 40, "track_score": 50, "milestone_score": 30, "field_heat_score": 40, "bonus_score": 0, "brief_reason": "L19-AuNP为靶向纤维连接蛋白额外结构域B（FN-EDB）的金纳米粒子，用于神经母细胞瘤的靶向诊断成像，由医院机构主导研究，Nano Flow仅提供纳米粒子制备。机构为医院类型且开发处于初步preclinical阶段，无热门modality或靶点亮点，导致总体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6258", "id": "gFXM_5wBX1NQZOEH-LK6", "source_drug_name": "L19-AuNP", "title": "Fibronectin extra-domain B-recognizing gold nanoparticles as an innovative tool for neuroblastoma targeting", "abstract_text": "Background/Objectives: Neuroblastoma (NB) is the most common extracranial solid tumor in children and accounts for 12-15% of pediatric cancer-related deaths. Current multimodal therapies still lack of specific cellular targets, causing systemic toxicity and drug resistance. The development of innovative tumor-targeted nanoformulations might represent a promising approach to enhance NB diagnosis and antitumor efficacy, while decreasing off targets side effects. Fibronectin extra-domain B (FN-EDB) is upregulated in the tumor microenvironment.\nMethods: Here, FN-EDB expression was evaluated by immunohistochemical (IHC) staining in several animal models of NB. A gold nanoparticle, decorated with an antibody (Ab) recognizing FN-EDB (L19-AuNP) was developed by the company Nano Flow and its tumor binding was tested by ELISA in vitro and in Patient-Derived Xenografts (PDX) models of NB by photoacoustic imaging in vivo.\nResults: All models of NB used expressed FN-EDB, at the tumor cell, stroma and tumor vasculature levels. Compared to the non-targeted (no L19 Ab) Au-NP (size: 35.59 ± 2.54 nm; PDI: 0.47 ± 0.08; zeta potential: -51.18 ± 0.84), L19-AuNP was found to be stable (size: 108.70 ± 1.37 nm; PDI: 0.29 ± 0.07; zeta potential: -28.34 ± 0.48) and able to specifically bind to FN-EDB in vitro. In vivo, L19-AuNP specifically homed into PDX of NB, accumulating more in the tumor expressing higher levels of FN-EDB.\nConclusions: In this preliminary study, L19-AuNP was shown to be a novel diagnostic tool specific for binding NB expressing FN-EDB, paving the way for the development of theranostic nanoformulations co-encapsulating gold moiety and standard-of-care for NB.", "source_company": "IRCCS Ospedale Policlinico San Martino", "source_org_type": "医院", "row_number": 570, "target_meta": "EDB-FN", "MOA_meta": "其他"}, {"drug_name": "dominant negative protein", "company": "Silvester Comprehensive Cancer Center", "org_type": "医院", "target": "sTNF", "modality": "dominant negative protein", "importance_level": "低", "total_score": 39, "institution_score": 25, "track_score": 45, "milestone_score": 55, "field_heat_score": 50, "bonus_score": 2, "brief_reason": "药物为针对可溶性TNF的dominant negative protein，在HER2+乳腺癌模型中联合TKI显著抑制肿瘤生长和转移，但靶点sTNF在肿瘤治疗中非主流热点。机构为医院/学术中心，开发阶段属preclinical早期，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8918", "id": "qlXM_5wBX1NQZOEH-LO6", "source_drug_name": "dominant negative protein", "title": "Soluble TNF blockade as a strategy to enhance tyrosine-kinase inhibitor response and control metastatic burden in HER2-positive breast cancer", "abstract_text": "Tyrosine kinase inhibitors (TKIs), such as lapatinib and tucatinib, are used to treat metastatic HER2-positive breast cancer, especially those located in the brain, as they can cross the blood-brain barrier. Although both TKIs improve survival, there is still an urge to boost their efficacy and overcome resistance. We have demonstrated that soluble TNF (sTNF) blockade overcomes resistance to trastuzumab-based therapies targeting HER2 by downregulating mucin 4 (MUC4), which shields its epitope on the HER2 molecule. Now, we asked whether sTNF neutralization might overcome TKI-based therapy resistance or enhance its antitumor activity.We used the HER2+/MUC4+ JIMT-1 and its brain-tropic subline JIMT-1BR3-luc cell lines, resistant to lapatinib. For proliferation and cell migration assays, cells were treated with 1 µM lapatinib or 10 µM tucatinib, either alone or combined with 10 µg/ml of a dominant negative (DN) protein that neutralizes sTNF. For preclinical studies, female nude mice bearing JIMT-1 tumors received vehicle, 100 mg/kg lapatinib via oral gavage daily, 10 mg/kg DN i.p. twice a week, or the combination (n=5/group). For JIMT-1BR3-luc tumors, mice were treated with vehicle, 100 mg/kg tucatinib via oral gavage daily, DN twice weekly, or both (n=9/group). Tumor volume was measured biweekly for 21 days; metastases were detected ex vivo by IVIS luminescence.Neither lapatinib nor DN alone impacted JIMT-1 cell proliferation, but their combination reduced cell proliferation by 60%. For JIMT-1Br-luc cells, DN and tucatinib decreased cell proliferation by 35 % and 55%, respectively, and the combination enhanced the effect to 80%. Cell migration was significantly inhibited in both cell lines by their respective combo treatment, compared to the monotherapies.In preclinical studies, treatment with DN, lapatinib, or tucatinib did not affect the primary tumor growth, compared to the vehicle. However, the combination of DN and lapatinib reduced JIMT-1 tumor growth by 77% and, in the case of JIMT-Br-luc tumors, treatment with DN and tucatinib inhibited tumor growth by 68%, compared to the monotherapies. The percentage of JIMT-Br-luc tumor-bearing mice with lung metastases was 100% in the vehicle group, 75% in the DN group, 37.5% in the tucatinib group, and 12.5% in the combined group. Animals with brain and liver metastases accounted for 50% and 75% respectively, in the vehicle group, and were 90-100% reversed upon treatment with either tucatinib or DN, or the combination.These findings highlight that sTNF blockade can overcome lapatinib resistance and improve tucatinib inhibitory effect on cell proliferation, both in vitro and in vivo. In addition, DN was able to curb brain and liver metastasis and lung metastases in combination with tucatinib, underscoring the potential benefit of its use in combination with TKIs in advanced HER2-positive breast cancer patients.", "source_company": "Silvester Comprehensive Cancer Center", "source_org_type": "医院", "row_number": 765, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "IL-24-iMSC", "company": "Chinese University of Hong Kong", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 39, "institution_score": 25, "track_score": 65, "milestone_score": 35, "field_heat_score": 50, "bonus_score": 0, "brief_reason": "IL-24-iMSC为工程化iPSC来源间充质干细胞，通过持续分泌IL-24重塑NSCLC免疫抑制性肿瘤微环境，靶点未明确披露。大学机构研发+动物模型初步免疫重塑证据，但preclinical早期且无肿瘤生长抑制，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9616", "id": "slXM_5wBX1NQZOEH-LS6", "source_drug_name": "IL-24-iMSC", "title": "IL-24 engineered mesenchymal stem cells as a novel therapeutic strategy to remodel the tumor microenvironment in non-small cell lung cancer", "abstract_text": "Immune checkpoint inhibitor (ICI) resistance in non-small cell lung cancer (NSCLC) is frequently driven by an immunosuppressive tumor microenvironment (TME). To address this issue, we developed IL-24-iMSC, a novel mesenchymal stem cell-based therapy designed to remodel the immunosuppressive tumor microenvironment through sustained secretion of interleukin 24 (IL-24), an immunomodulatory cytokine with anti-cancer properties. Induced mesenchymal stem cells (iMSCs) were derived from induced pluripotent stem cells (iPSCs) and the IL-24 gene was integrated into iMSC at the B2M locus under the control of the EF1α promoter using CRISPR/Cas. IL-24-iMSCs were confirmed to constitutively secrete IL-24. Metastatic lung cancer models were established by tail vein injection of Lewis Lung Carcinoma cells expressing luciferase (LLC-luc) into immunocompetent C57BL/6 mice. Tumor progression was monitored using an In Vivo Imaging System (IVIS). Treatment was administered 20 days after tumor inoculation, and mice were randomized into three groups: iMSC, IL-24-iMSC, or vehicle control. All mice were sacrificed three days after treatment. Tumor growth was confirmed by bioluminescence imaging using IVIS, and tumor samples were collected for immune profiling. While there was no significant difference in tumor growth among the three groups, tumors exposed to IL-24-iMSC demonstrated a pro-inflammatory phenotype. Multiplex immunohistochemistry confirmed infiltration of MSCs into the TME, with significantly increased IL-24 expression in the IL-24-iMSC arm. Compared with the control group (untreated), tumors treated with IL-24-iMSC showed increased CD8+ T cells, dendritic cells, and memory CD4+ T cells. IFN-γ and TNF-α expressions were also elevated in the IL-24-iMSC treatment arm. On the contrary, regulatory T cells and exhausted T cells (PD1+ TIM3+) were significantly reduced in the IL-24-iMSC group. In conclusion, IL-24-iMSCs demonstrated the ability to modulate immune cell composition within the tumor microenvironment, suggesting their potential to synergize with ICI in NSCLC.", "source_company": "Chinese University of Hong Kong\nThe Chinese University of Hong Kong", "source_org_type": "大学", "row_number": 962, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "a novel compound for hepatocellular carcinoma", "company": "Michigan State University", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 39, "institution_score": 25, "track_score": 45, "milestone_score": 55, "field_heat_score": 40, "bonus_score": 3, "brief_reason": "该化合物针对肝细胞癌，通过深度学习转录组表型逆转设计，靶点和具体机制未披露。大学机构分数较低，赛道为AI辅助小分子药物发现有一定新颖性但非热门modality，体外优化和初步体内活性里程碑一般，故总体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6532", "id": "h57M_5wBZznHJdnt_W3O", "source_drug_name": "a novel compound for hepatocellular carcinoma", "title": "Deep learning-based screening and design of novel therapeutics that reverse cancer-associated transcriptional phenotypes", "abstract_text": "Identifying drugs that reverse expression of disease-associated transcriptomic features has been widely explored as a strategy for discovering drug repurposing candidates, but its potential for novel compound discovery and optimization remains largely underexplored. Here, we present a deep learning-based drug discovery platform, guided by transcriptomic features, that screens large compound libraries and optimizes lead compounds. We first develop a model that predicts gene expression changes solely from chemical structures and deploy it to infer the expression changes induced by compounds in large screening libraries. We then refine compound scoring and employ a Monte Carlo Tree Search method for multi-objective optimization. By incorporating Structure-Gene-Activity Relationships, we uncover drug mechanisms directly from transcriptomic data. To demonstrate the utility of the system, we identify and validate compounds for hepatocellular carcinoma (HCC). In HCC, we design a novel compound that improves the IC50 from 4 µM to 0.5 µM, with increased in vitro selectivity, favorable pharmacokinetics and in vivo activity.", "source_company": "Michigan State University", "source_org_type": "大学", "row_number": 1040, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "Levistolide A", "company": "Jeju National University", "org_type": "大学", "target": "GPX4", "modality": "other", "importance_level": "低", "total_score": 39, "institution_score": 20, "track_score": 75, "milestone_score": 40, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "Levistolide A通过下调GPX4表达诱导铁死亡，抑制膀胱癌进展。机构为韩国大学，处于体外+裸鼠模型的preclinical早期阶段，非热门modality且无产业化背景，导致总体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4599", "id": "k57M_5wBZznHJdnt_W7P", "source_drug_name": "Levistolide A", "title": "Levistolide A inhibits bladder cancer progression by suppressing GPX4 expression and activating ferroptosis", "abstract_text": "Bladder cancer is the second most common malignant tumor of the urinary system worldwide, with high incidence and mortality rates. However, existing drugs for treating bladder cancer often cause many adverse reactions. Levistolide A (LA), a natural compound isolated from the traditional Chinese herb Ligusticum chuanxiong Hort, has been identified as an anti-cancer agent. However, its role in bladder cancer and underlying mechanisms remain largely unknown. In this study, we used the MTT assay and Annexin V/PI staining to detect the co-induced death of bladder cancer cell lines 5637 and T24 by LA and different cell death inhibitors. The rescue experiment show that ferrostatin-1 (Fer-1, ferroptosis inhibitor) could rescue the proliferation of bladder cancer cells prevented by LA or not other inhibitors of cell death. At the same time, through in vivo verification using a xenograft model, LA can effectively inhibit the proliferation of bladder cancer cell line 5637. Subsequent RNA-seq analysis, nude mouse tumor model, MDA detection, and Western blotting, demonstrated that LA-enhanced lipid peroxidation by up-regulating PTGS2 and down-regulating GPX4, accompanied by dysregulation of intracellular iron homeostasis. Furthermore, we also found that in in vivo experiments, co-treatment with LA and RSL3 (ferroptosis inducer) increased the inhibitory effect on bladder cancer cells 5637, highlighting its potential for clinical application. This provides a novel therapeutic strategy for eliminating bladder cancer cells.", "source_company": "Jeju National University", "source_org_type": "大学", "row_number": 1224, "target_meta": "GPX4", "MOA_meta": "其他"}, {"drug_name": "C5", "company": "Texas Tech University Health Sciences Center", "org_type": "大学", "target": "未披露", "modality": "inhibitor", "importance_level": "低", "total_score": 38.5, "institution_score": 35, "track_score": 40, "milestone_score": 35, "field_heat_score": 45, "bonus_score": 0, "brief_reason": "C5为新型磺酰胺-芳香胺杂合小分子化合物，靶点未明确披露，仅通过转录组提示可能涉及DNA损伤和谷胱甘肽代谢相关基因。大学机构、非热门靶点、仅细胞水平初步筛选且机制研究尚在进行中，导致整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6560", "id": "elXM_5wBX1NQZOEH-LK6", "source_drug_name": "C5", "title": "Novel sulfonamide-aromatic amine hybrids: Synthesis, cytotoxic screening, and transcriptomic insights into anticancer activity", "abstract_text": "Cancer remains one of the causes of mortality worldwide and a major global health challenge. These challenges are attributed to factors such as medication resistance, tumor complexity, and heterogeneity. Targeted therapy with small molecules has emerged as a promising approach due to its ability to selectively inhibit cancer cell growth while minimizing off-target effects. In this study, a series of derivatives synthesized from 3-formyl-4-hydroxy benzene sulfonyl chloride (FHS) were evaluated for their cytotoxic effects on various cancer cells. The objective was to identify compounds with potent anticancer activity and favorable selectivity profiles for further development. The synthesis process began with FHS as the starting material, subjected to a series of chemical reactions to generate a library of compounds labeled C3 through C10. These compounds were characterized by using a combination of analytical techniques, including melting point determination, Proton Nuclear Magnetic Resonance (1H NMR), Carbon-13 Nuclear Magnetic Resonance (13C NMR), and Infrared (IR) spectroscopy to confirm their structural integrity. Cytotoxic effects were evaluated using Sulforhodamine B (SRB) assay for cytotoxicity was applied to an extensive panel of cancer cell lines, categorized into such as colorectal cancer (HT-29, MC38, CT26and COLO 205), hepatic (C3a and PLC/PRF), pancreatic (Suit-2, MiaPaca2, As-PC1 and Panc 02.03, CI66), breast (MDA-MB-468, MDA-MB-231, BT20, MCF7, 4T1, 4T1 paclitaxel resistant, JIMT-1, ZR-75-1, E0771, T47D, and HCC1806) and ovarian (OVCAR-5) cell lines. Normal breast epithelial cell line MCF10a was tested to analyze safety. Based on the SRB assay, 7 compounds exhibited variable but significant cytotoxicity in various cancer models. The most effective compound, C5, was chosen for further analysis to identify mechanism of its cytotoxic effect by transcriptomic analysis. The transcriptomic results showed ten genes with log2 fold change between control and treatment. These genes were related to DNA damage inducible transcript 4, FXYD domain containing ion transport regulator 4 and CHAC1 (glutathione-specific gamma-glutamylcyclotransferase 1). Further in vivo experiments and validation experiments are in progress to determine the most significant pathway for cytotoxicity.", "source_company": "Texas Tech University Health Sciences Center", "source_org_type": "大学", "row_number": 564, "target_meta": "not available", "MOA_meta": "抑制剂"}, {"drug_name": "Neohesperidin dihydrochalcone", "company": "Jeju National University", "org_type": "大学", "target": "System Xc−", "modality": "other", "importance_level": "低", "total_score": 38.5, "institution_score": 25, "track_score": 60, "milestone_score": 30, "field_heat_score": 50, "bonus_score": 3, "brief_reason": "NHDC是一种天然黄酮类甜味剂，通过抑制System Xc−途径减轻脂质ROS积累，展现抗铁死亡活性。机构为韩国大学基础研究，处于体外机制探索早期阶段，赛道有一定热度但无临床开发迹象，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6540", "id": "nlXM_5wBX1NQZOEH-LK6", "source_drug_name": "Neohesperidin dihydrochalcone", "title": "Neohesperidin dihydrochalcone: A novel natural inhibitor of ferroptosis", "abstract_text": "Ferroptosis, a form of regulated cell death characterized by the iron-dependent accumulation of lipid peroxides, is increasingly recognized as a critical pathogenic mechanism in various human diseases. Given the significant implication of ferroptosis in pathology, there is an urgent need to identify novel chemotypes with anti-ferroptotic activity. Recently, natural products have garnered attention as safe and effective sources for ferroptosis regulators. In this study, we identified Neohesperidin dihydrochalcone (NHDC), a flavonoid sweetener derived from citrus fruits, as a potent inhibitor of ferroptosis. We demonstrated that NHDC significantly restored cell viability in HT-1080 cells treated with Erastin, a System Xc− inhibitor. Mechanistically, NHDC treatment effectively mitigated the accumulation of lipid reactive oxygen species (ROS) and modulated the expression of ferroptosis-related proteins, including SLC3A2, SLC7A11, and PTGS2. Furthermore, NHDC exhibited a protective effect against ferroptosis induced by Sulfasalazine (SAS), another System Xc− inhibitor, by reverting SAS-induced lipid ROS levels. Interestingly, NHDC showed selectivity in its protective mechanism, distinguishing its activity from RSL3-induced ferroptosis pathways. Collectively, our findings demonstrate that NHDC acts as an effective anti-ferroptotic agent by targeting System Xc− inhibition. This study provides valuable insights into the therapeutic potential of NHDC as a natural candidate for the treatment of ferroptosis-related diseases.", "source_company": "Jeju National University", "source_org_type": "大学", "row_number": 586, "target_meta": "system xc−", "MOA_meta": "其他"}, {"drug_name": "desmethyl-clomipramine", "company": "Baylor College of Medicine", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 38.5, "institution_score": 30, "track_score": 40, "milestone_score": 45, "field_heat_score": 50, "bonus_score": 0, "brief_reason": "desmethyl-clomipramine为抗抑郁药旧药，未披露明确新靶点，主要通过抑制自噬和辅助降低MCL-1发挥增敏化疗作用，机制为再利用而非新药开发。机构为大学，赛道非热门创新modality且处于基础体外研究阶段，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6079", "id": "BFXM_5wBX1NQZOEH-LS6", "source_drug_name": "desmethyl-clomipramine", "title": "Mcl-1 inhibitors and antidepressants as enhancers of chemotherapy response in pleural mesothelioma", "abstract_text": "Background: Pleural mesothelioma (PM) remains a highly lethal malignancy with limited therapeutic options. Chemotherapy with cisplatin (CDDP) and pemetrexed provides modest benefit which is limited by primary resistance mechanisms involving dysregulated apoptotic signaling. Myeloid Cell Leukemia (MCL)-1 is a Bcl-2 family member that blocks apoptosis by targeting the mitochondria which works synergistically with activation of autophagy to promote chemoresistance. Targeting MCL-1 lowers the apoptotic threshold and may suppress autophagy to enhance chemosensitivity and improve therapeutic response. This study aimed to determine whether combining MCL-1 inhibition with the antidepressant, desmethyl-clomipramine (DCMI), will enhance chemosensitivity via autophagy in PM cells.\nMethods: IC₅₀ calculations of CDDP, the MCL-1 inhibitor (AZD-5991), DCMI and the combinations were performed in PM cell lines H28 and H2452. Synergistic interactions were quantified using the Highest Single Agent (HSA) model. To explore autophagy, cells were treated with the autophagy inhibitor, chloroquine (CQ, 10 µM), as a positive control and analyzed for known markers, LC3 and p62, by Western blot. In addition, MCL-1 expression after DCMI combination treatments was evaluated. Cell death and apoptosis were evaluated by flow cytometry (Anexin V and PI) following treatment. Mitochondrial and glycolytic metabolic parameters were quantified by Seahorse XF.\nResults: CDDP + AZD-5991 exhibited robust synergy (HSA = 10.51, p < 0.0001 in H2452; HSA = 9.06, p < 0.0001 in H28). In contrast, CDDP and DCMI produced limited interaction in H2452 cells (HSA = 2.48, p = 0.0015) and a near-additive effect in H28 cells (HSA = 0.76, p = 0.175). However, the combination of CDDP, AZD-5991, and DCMI revealed synergistic activity at lower AZD-5991 concentrations, suggesting enhanced potency. DCMI promoted accumulation of p62 and delayed LC3-II processing, consistent with inhibition of autophagy. Furthermore, DCMI + AZD-5991 increased apoptotic cells relative to CDDP alone. These findings suggest enhancement of apoptotic signaling via combined inhibition of autophagy and MCL-1 activity. Seahorse analysis revealed that DCMI decreased basal respiration in H2452, with no effect on H28 bioenergetics. MCL-1 decreases under CDDP + DCMI versus CDDP alone, indicating that DCMI enhances apoptotic priming via MCL-1 suppression and mitochondrial dysfunction.\nConclusion: These findings support that complementary mechanisms of DCMI blocking autophagy and MCL-1 promoted apoptosis will enhance the response to cisplatin. This cooperative mechanism reveals metabolic and anti-apoptotic vulnerabilities that could be exploited to overcome chemoresistance in mesothelioma. Further investigation is warranted to assess whether blocking autophagy will increase patient’s response to chemotherapy.", "source_company": "Baylor College of Medicine", "source_org_type": "大学", "row_number": 832, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "CTLA-4 antibody", "company": "University of Michigan", "org_type": "大学", "target": "CTLA-4", "modality": "inhibitor", "importance_level": "低", "total_score": 38.5, "institution_score": 30, "track_score": 75, "milestone_score": 10, "field_heat_score": 40, "bonus_score": 0, "brief_reason": "CTLA-4抗体为经典免疫检查点抑制剂，靶点和机制成熟但非新颖。大学机构、非临床研究、无开发里程碑信息导致整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/453", "id": "rlXM_5wBX1NQZOEH-LS6", "source_drug_name": "CTLA-4 antibody", "title": "Microbiota-immune interactions in colitis induced by CTLA-4 antibody blockade", "abstract_text": "There is no abstract associated with this presentation.", "source_company": "University of Michigan", "source_org_type": "大学", "row_number": 959, "target_meta": "CTLA4", "MOA_meta": "抑制剂"}, {"drug_name": "S100A9 derivative Near-infrared fluorescent probe", "company": "University of Oklahoma Health Science", "org_type": "大学", "target": "CD147", "modality": "荧光显像剂", "importance_level": "低", "total_score": 38.5, "institution_score": 30, "track_score": 40, "milestone_score": 45, "field_heat_score": 50, "bonus_score": 0, "brief_reason": "该探针以S100A9衍生物为配体靶向CD147，用于PDAC的近红外荧光成像引导手术，优化了肽长度和偶联方向以提升结合力和降低非靶向积累。机构为大学、处于早期优化阶段、成像探针赛道非热门治疗方向，故综合重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6261", "id": "Jp7M_5wBZznHJdnt_W3O", "source_drug_name": "S100A9 derivative Near-infrared fluorescent probe", "title": "Optimizing an S100A9 probe to enhance CD147 targeting for image guided surgery of pancreatic ductal adenocarcinoma", "abstract_text": "Background: Pancreatic ductal adenocarcinoma, PDAC, remains of the deadliest cancers with the 5-year survival rate being 10-15%. Surgery is one of the only curable treatments for PDAC with up to 70% of patients that are candidates for surgery having positive margins; it is critical to have accurate imaging of PDAC which can contribute to patient stratification. S100A9 is a calcium binding ligand that binds to CD147, also designated as extracellular matrix metalloproteinase inducer (EMMPRIN), a membrane-bound glycoprotein. To better visualize PDAC cells, an S100A9 derivative Near-infrared fluorescent probe was created to have increased binding to CD147 while minimizing off-target accumulation.\nMethods: The pancreatic adenocarcinoma cancer cell lines, MiaPaca2, Panc1, Suit2, S2VP10 and S2013 were assessed for CD147 levels using western blot. The 114 amino acid S100A9 was synthesized using microwave chemistry and lyophilized. Hilyte 750 succinimidyl ester and Hilyte 750 amine reactive dyes were independently conjugated to the S100A9 peptide to determine the ideal orientation. Spectroscopy confirmed the conjugation of the probes. NIR imaging determined 750-S100A9 probes binding to S2VP10 cells. S100A9 peptide length was reduced to 89 or 80 amino acids and conjugated to HiLyte Fluor 750 acid SE dye on the C-Terminal end. Conjugation was tested with spectroscopy and the full length and cut down probes binding to S2VP10L were tested with NIR imaging.\nResults: The western blot demonstrated that MiaPaca2, Panc1 and S2013 were highly positive for CD147 while Suit2 and S2VP10 were less positive. Successful conjugation of peptides to the reactive dyes resulted in an OD of 0.1 each. 750 dye conjugated to the C-terminal of the S100A9 probe determined stronger binding to S2VP10 at 279,600 a.u. at 500 nM compared to 4,055 a.u. of N-terminal 750-S100A9 (p< 0.05). The 89 amino acid probe resulted in the highest expression at 291,760 a.u. compared to the full-length at 46,580 a.u. and the S100A9-750 80 amino acid probe at 115,200 a.u. when assessed with binding to S2013Q (p< 0.05).\nConclusion: CD147 is a suitable target for PDAC using an S100A9 ligand conjugated near infrared fluorescent dye. In addition, S100A9 cut down to 89 amino acids on the C-Terminal with the HiLyte Fluor 750 acid SE dye determines to be a strong target for PDAC. The findings suggest that off-target accumulation of S100A9 could be minimized with the use of the smaller probe. The results also suggest that the S100A9 probes can improve detection and treatment of PDAC specificity with contrast agents or nanoparticles.", "source_company": "University of Oklahoma Health Science", "source_org_type": "大学", "row_number": 977, "target_meta": "BSG", "MOA_meta": "荧光显像剂"}, {"drug_name": "hexamethylene amiloride", "company": "UC Davis", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 38.5, "institution_score": 30, "track_score": 50, "milestone_score": 35, "field_heat_score": 45, "bonus_score": 3, "brief_reason": "hexamethylene amiloride (HMA) 为amiloride衍生物，通过诱导ROS和溶酶体依赖的程序性坏死机制选择性杀伤肿瘤细胞（包括TNBC中的CSC），但靶点未明确披露。UC Davis大学学术机构研发，处于preclinical阶段，机制新颖但非热门modality和靶点，整体开发热度和里程碑价值有限。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8904", "id": "Kp7M_5wBZznHJdnt_W7O", "source_drug_name": "hexamethylene amiloride", "title": "Involvement of ROS species in amiloride derivative-induced lysosome-dependent cell death in triple-negative breast cancer cells", "abstract_text": "Drug resistance leading to cancer recurrence poses a particularly challenging barrier to clinical disease management. Since tumor cells commonly activate anti-apoptotic pathways that cause caspase-dependent pathways to malfunction, cellular resistance to apoptosis is perhaps the most critical factor contributing to the therapeutic failure of conventional and targeted therapeutic agents. Consequently, subpopulations of apoptosis-resistant cells, such as cancer stem cells (CSCs), persist after therapy to seed primary tumor recurrence and metastatic lesions, even after complete remission. The overarching goal of this project is to develop novel drugs that exploit the process of lysosome-dependent cell death, a programmed necrotic cell death mechanism, in suppressing CSC-mediated triple-negative breast cancer. We have previously observed that hexamethylene amiloride (HMA), a derivative of the FDA-approved diuretic amiloride, is cytotoxic in vitro and ex vivo toward cultured cells from a variety of tumor types but not non-transformed cells. HMA also suppresses primary and metastatic tumor outgrowth in vivo. HMA acts on breast tumor cells regardless of subtype, proliferative status, or species of origin. It engages a potent caspase- and autophagy-independent programmed necrotic death mechanism in tumor cells that alters lysosome structure, dysregulates lipid synthesis, leads to lysosomal membrane permeabilization, and acts efficiently toward therapy-resistant CSC-related subpopulations. Although some specifics of the mechanism remain unknown, we examine how the formation of reactive oxygen species is crucial to the induction of necrosis and the potency of HMA and other amiloride derivatives.", "source_company": "UC Davis", "source_org_type": "大学", "row_number": 1153, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "aromatase inhibitor", "company": "Dartmouth Cancer Center", "org_type": "医院", "target": "aromatase", "modality": "inhibitor", "importance_level": "低", "total_score": 38.5, "institution_score": 35, "track_score": 45, "milestone_score": 30, "field_heat_score": 50, "bonus_score": 0, "brief_reason": "aromatase inhibitor为经典内分泌治疗药物，靶向aromatase抑制雌激素合成，用于ER+乳腺癌。机构为医院学术中心、非商业开发，赛道为成熟领域无新机制，摘要仅为回顾性临床观察研究，无创新药物推进价值。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1905", "id": "RZ7M_5wBZznHJdnt_W7O", "source_drug_name": "aromatase inhibitor", "title": "Obesity predicts greater changes in Ki67 after neoadjuvant aromatase inhibitor therapy in early-stage ER+ breast cancer", "abstract_text": "Background: Nearly 70% of breast cancers are ER positive (ER+), and anti-estrogen therapy, such as tamoxifen and aromatase inhibitors (AI), are a mainstay of treatment. Neoadjuvant endocrine therapy (NET) with aromatase inhibitors is effective at reducing tumor burden and may be predictive of better long-term outcomes. A significant decrease in Ki-67 is prognostic but additional predictive clinical factors for improved response to NET are not well understood. Preliminary data from our post-menopausal cohort of women with ER+ early-stage breast cancers treated with NET presented at the San Antonio Breast Cancer Symposium 2025, showed correlation between larger tumor sizes and greater radiographic response to NET with 68% of tumors exhibiting a radiographic response. Women with higher BMI have a higher risk of breast cancer recurrence and mortality, hypothesized to be due to incomplete suppression of aromatase but specific data on response to NET is lacking.\nObjective: Determine the association between BMI and change in Ki67 expression after NET in patients with early-stage breast cancer.\nMethods: 150 post-menopausal women with Stage I-III ER+, HER2- breast cancer were treated with an aromatase inhibitor for 7-168 days (mean 42.83 days) prior to surgery and had BMI, pre- and post-NET Ki67 immunohistochemistry available. Digital Ki-67 analysis on the diagnostic biopsy before NET was compared to Ki-67 on the surgical specimen. Statistical analysis determined p-values from the pairwise t-test. Control group analysis is in progress.\nResults: The mean Ki-67 prior to NET was 18.62% (range 0.69%- 61.56%). The mean Ki-67 after NET was 4.17% (range 0.04%- 46.07%). The mean radiographic baseline tumor size 20.9 mm. We found that both BMI and the baseline tumor size significantly correlated with Ki-67 expression difference (p=0.038 and p= 0.026, respectively). For example, based on our analysis, it is expected that women with a BMI = 30, there will be a two-fold decrease in post-NET Ki-67 expression. There was no significant correlation between change in Ki-67 and number of days on NET.\nDiscussion: In our cohort, higher BMI was associated with a greater decrease in Ki-67 expression compared to women with BMI <30, suggesting greater suppression of cell proliferation by NET in obese women. Suppression of Ki-67 is considered a good prognostic indicator, therefore this preliminary data contradicts the hypothesis that poorer outcomes for women with breast cancer and a BMI >30 are due to insufficient response to aromatase inhibitors. Additional research is needed to further elucidate these findings and validate this data against long-term AI adherence and other predictors of outcomes.", "source_company": "Dartmouth Cancer Center", "source_org_type": "医院", "row_number": 1173, "target_meta": "aromatase", "MOA_meta": "抑制剂"}, {"drug_name": "STMN1 inhibitor", "company": "Anhui Medical University", "org_type": "大学", "target": "STMN1", "modality": "inhibitor", "importance_level": "低", "total_score": 38, "institution_score": 20, "track_score": 60, "milestone_score": 40, "field_heat_score": 50, "bonus_score": 0, "brief_reason": "靶点为STMN1（微管不稳定蛋白），通过IGF1R-STMN1轴促进骨肉瘤转移，摘要中双靶向抑制显示体外体内抑制侵袭和转移潜力。机构为大学非商业研发，赛道非热门modality且STMN1无成熟药物，处于基础机制研究阶段，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10289", "id": "OVXM_5wBX1NQZOEH-LG5", "source_drug_name": "STMN1 inhibitor", "title": "Spatial co-elevation of IGF1R and STMN1 associates with metastatic progression in osteosarcoma", "abstract_text": "Background: Osteosarcoma metastasis remains the leading cause of patient mortality, and current therapeutic strategies offer limited benefit for metastatic disease. Identifying metastasis-associated signaling programs is essential for developing more effective interventions.\nMethods: We integrated single-cell RNA sequencing, spatial transcriptomics, ligand-receptor interaction analysis, and functional assays to define molecular programs associated with osteosarcoma progression. Clinical cohorts were used to evaluate associations with metastasis and survival. In vitro and in vivo models were applied to validate mechanistic insights and therapeutic response.\nResults: High IGF1R and STMN1 expression strongly correlated with distant metastasis and poor prognosis. Single-cell communication analysis revealed enhanced crosstalk between STMN1⁺ osteosarcoma cells and cancer-associated fibroblasts (CAFs), predominantly driven by IGF-mediated signaling. Spatial transcriptomics confirmed the co-localization and coordinated upregulation of IGF1R and STMN1 in metastatic niches. Functional assays demonstrated that stromal IGF1/IGF2 activation of IGF1R increases STMN1 expression, and stronger spatial co-elevation of these molecules reflects enhanced coordination that facilitates tumor dissemination. Dual targeting of IGF1R and STMN1 significantly suppressed osteosarcoma invasion and metastatic outgrowth in both in vitro and in vivo models.\nConclusions: This study identifies the IGF1R-STMN1 axis as a mechanistically coherent and spatially reinforced driver of osteosarcoma metastasis. The spatial co-elevation of IGF1R and STMN1 marks metastatic niches and represents a promising therapeutic vulnerability, offering new avenues for improving outcomes in osteosarcoma.", "source_company": "Anhui Medical University", "source_org_type": "大学", "row_number": 10, "target_meta": "STMN1", "MOA_meta": "抑制剂"}, {"drug_name": "cystine-conjugated liposome", "company": "Western University of Health Sciences", "org_type": "大学", "target": "xCT", "modality": "other", "importance_level": "低", "total_score": 38, "institution_score": 30, "track_score": 60, "milestone_score": 20, "field_heat_score": 50, "bonus_score": 0, "brief_reason": "该制剂利用cystine靶向xCT转运体实现脂质体细胞摄取优化，机制为配体密度调控的靶向递送；但来自大学基础研究，仅preclinical细胞水平优化，无明确药物负载或治疗里程碑，机构非头部公司且赛道非热门ADC/双抗等。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5697", "id": "llXM_5wBX1NQZOEH-LO6", "source_drug_name": "cystine-conjugated liposome", "title": "Optimizing targeting molecule density on drug carriers to improve cellular uptake", "abstract_text": "Purpose: The purpose of this work is to determine whether the number of targeting molecules on a carrier correlates with improved cell uptake. The xCT transporter is a cell-surface facilitative transporter that imports cystine into the cell and exports glutamate. Using liposomes as the carrier, we conjugated varying amounts of cystine, the targeting agent, to their surfaces to harness the xCT transporter. We evaluated the cellular uptake of liposomal formulations with different levels of the targeting molecule conjugated to the liposomal surface (A: medium, B: low, C: high) in several cell lines.\nMethods: Liposomes with different levels of the targeting molecule were formulated, and sulforhodamine B (SRB), a fluorescent dye, was encapsulated in the liposomes. The formulations tested were: three targeted formulations with varying levels of the targeting molecule (A: medium, B: low, C: high), one non-targeted formulation (NT), and an untreated control. These formulations were incubated for 6 hours with five human cancer cell lines (BxPC-3, MIA PaCa-2, A549, OVCAR-8, and PANC-1). After incubation, the cell lines were washed three times, and liposome uptake was quantified by measuring the mean fluorescence intensity of SRB using flow cytometry (Attune NxT, Acoustic Focusing Cytometer, Thermo Fisher Scientific, MA).\nResults: Targeted liposomes consistently demonstrated significantly higher uptake than the non-targeted formulation across all five cell lines tested. However, the correlation between targeting-molecule density and uptake was cell-line-dependent. The formulation with the highest targeting molecule density (Formulation C) showed the highest uptake in three of the five cell lines (BxPC-3, MIA PaCa-2, and A549). In contrast, varying the targeting molecule density did not result in a statistically significant difference in uptake among the targeted formulations in the OVCAR-8 and PANC-1 cell lines.\nConclusion: The data suggest that cells' ability to internalize liposomes depends on whether the liposomes carry a targeting molecule. However, the extent of internalization is cell line dependent.", "source_company": "Western University of Health Sciences", "source_org_type": "大学", "row_number": 58, "target_meta": "SLC7A11", "MOA_meta": "其他"}, {"drug_name": "ApoA1-Anti CD99 antibody fusion protein", "company": "Children's Hospital Los Angeles", "org_type": "医院", "target": "CD99", "modality": "other", "importance_level": "低", "total_score": 38, "institution_score": 30, "track_score": 60, "milestone_score": 20, "field_heat_score": 40, "bonus_score": 0, "brief_reason": "融合蛋白以CD99为靶点，ApoA1可能用于递送或功能增强，针对Ewing sarcoma；摘要被embargo，机构为医院非商业公司、开发阶段不明且无明确临床前里程碑，导致整体分数较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11295", "id": "uVXM_5wBX1NQZOEH-LG6", "source_drug_name": "ApoA1-Anti CD99 antibody fusion protein", "title": "Enhanced therapeutic efficacy of ApoA1-Anti CD99 antibody fusion protein for treatment of Ewing sarcoma", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Children's Hospital Los Angeles", "source_org_type": "医院", "row_number": 195, "target_meta": "CD99", "MOA_meta": "其他"}, {"drug_name": "KS100", "company": "Cooper Medical School of Rowan University", "org_type": "大学", "target": "pan-ALDH", "modality": "inhibitor", "importance_level": "低", "total_score": 38, "institution_score": 25, "track_score": 45, "milestone_score": 45, "field_heat_score": 50, "bonus_score": 2, "brief_reason": "KS100为新型pan-ALDH抑制剂，针对ALDH+多发性骨髓瘤干样细胞，机制新颖可克服耐药并与标准治疗协同。大学机构+早期体外/体内preclinical数据，赛道非主流热门导致综合重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4696", "id": "DFXM_5wBX1NQZOEH-LK6", "source_drug_name": "KS100", "title": "Aldehyde dehydrogenase inhibition as a strategy to overcome drug-refractory multiple myeloma", "abstract_text": "Multiple myeloma (MM) remains an incurable hematologic malignancy characterized by inevitable relapse and progressively therapy-resistant disease, despite the widespread use of combination regimens and autologous stem cell transplantation (ASCT). While only ~30% of patients achieve a complete response following initial therapy and ~40-50% with ASCT, the durability of these responses is limited, underscoring the persistence of highly drug-refractory cellular subpopulations. Increasing evidence implicates multiple myeloma stem-like cells (MMSLCs), a CD138⁻/ALDH⁺ phenotype enriched for self-renewal, metabolic plasticity, and intrinsic chemoresistance, as key drivers of relapse. Aldehyde dehydrogenases (ALDHs) promote MM survival by detoxifying cytotoxic aldehydes and sustaining retinoic acid-dependent stemness pathways, making them attractive therapeutic targets. We report the development and characterization of KS100, a novel pan-ALDH inhibitor, which potently eliminates both bulk MM cells and MMSLC populations in treatment-naïve and treatment-resistant models in vitro and in vivo. KS100 significantly reduces clonogenic growth, exhausts the ALDH-high compartment, and synergizes with standard MM therapies, including proteasome inhibitors and IMiDs, even in models with established resistance. These findings demonstrate that ALDH inhibition disrupts a universal resistance mechanism and position KS100 as a promising therapeutic strategy to eradicate stem-like reservoirs and improve long-term disease control in MM.", "source_company": "Cooper Medical School of Rowan University", "source_org_type": "大学", "row_number": 500, "target_meta": "not available", "MOA_meta": "抑制剂"}, {"drug_name": "peptides targeting PIP4K2A", "company": "Samsung Medical Center", "org_type": "医院", "target": "PIP4K2A", "modality": "other", "importance_level": "低", "total_score": 38, "institution_score": 30, "track_score": 60, "milestone_score": 20, "field_heat_score": 40, "bonus_score": 0, "brief_reason": "药品为靶向PIP4K2A的肽类，PIP4K2A在PTEN缺陷肿瘤中负调控PI3K通路，抑制其可能激活信号促进肿瘤，但机制需进一步验证。机构为医院学术型，非主流药企，摘要禁运无具体开发阶段信息，仅概念提出，整体早期热度有限。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11571", "id": "RlXM_5wBX1NQZOEH-LO6", "source_drug_name": "peptides targeting PIP4K2A", "title": "Peptides targeting PIP4K2A : A novel therapeutic strategy for PTEN-deficient cancer", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Samsung Medical Center\nSamsung Medical Center-Sungkyunkwan University School of Medicine", "source_org_type": "医院", "row_number": 701, "target_meta": "PIP4K2A", "MOA_meta": "其他"}, {"drug_name": "β,β-dimethylacrylalkannin", "company": "Zhengzhou University Medical College", "org_type": "大学", "target": "FGFR1", "modality": "inhibitor", "importance_level": "低", "total_score": 38, "institution_score": 20, "track_score": 60, "milestone_score": 50, "field_heat_score": 50, "bonus_score": 0, "brief_reason": "药物为天然萘醌类小分子，直接靶向抑制FGFR1，在体外和PDX模型中显示抗CRC活性。机构为大学，preclinical阶段无明显临床推进，赛道FGFR1在CRC中非最热门，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1879", "id": "w1XM_5wBX1NQZOEH-LO6", "source_drug_name": "β,β-dimethylacrylalkannin", "title": "β,β-dimethylacrylalkannin inhibits colorectal cancer growth in vitro  and in vivo by targeted FGFR1", "abstract_text": "Background: Colorectal cancer (CRC) continues to be a major global heaith challenge, ranking as a top cause of cancer-related death fatalities. Alarmingly, the five-year survival rate for CRC patients hovers around a mere 10-30%. The disruption of fibroblast growth factor receptor (FGFRs) signaling pathways is significantly implicated in the onset and advancement of colorectal cancer (CRC), presenting a promising target for therapeutic intervention in CRC management. Further investigation is essential to comprehensively elucidate the role of FGFR1 in CRC and to develop effective FGFR1-targeted therapies.\nPurpose: This study aims to demonstrate the oncogenic role of FGFR1 in colorectal cancer and investigate the potential therapeutic benefits of inhibiting FGFR1 activity using β, β-dimethylacrylalkannin (β,β-DMAA) as an FGFR1 inhibitor.\nMethods: In the present study, we performed tissue array, kinase profiling analysis assay, computational docking model, knockdown assay to predict and explore the inhibitor of FGFR1. Furthermore, we utilized kinase assay, pull-down, cell proliferation and Patient derived xenograft (PDX) mouse model assays to discover an FGFR1 inhibitor and assess its effects on colorectal cancer growth.\nResults: In this study, we found that FGFR1 protein is significantly overexpressed in colorectal cancer and plays a pivotal role in regulated cell growth, particularly in colorectal cancer patients. Furthermore, we conducted a computational docking, kinase profiling analysis, simulation and identified that β,β-DMAA could directly bind with FGFR1 within ATP binding pocket domain. Cell-based assays confirmed that β,β-DMAA not only inhibited the growth of colon cancer cells but also induced cell cycle arrest, apoptosis, and the modulation of FGFR1-mediated signaling pathways. Moreover, β,β-DMAA effectively attenuated the growth of PDX tumors in mice that were FGFR1-positive, all without causing significant toxicity. In summary, our study highlights the pivotal role of FGFR1 in colorectal cancer, suggesting that inhibiting FGFR1 activity could be a promising strategy for therapeutic intervention. We present strong evidence that targeting FGFR1 with β,β-DMAA is a viable approach for the management of colorectal cancer. Given its low toxicity and high efficacy, β,β-DMAA, as an FGFR1 inhibitor, warrants further investigation in clinical settings for the treatment of FGFR1-positive tumors.", "source_company": "Zhengzhou University Medical College", "source_org_type": "大学", "row_number": 784, "target_meta": "FGFR1", "MOA_meta": "抑制剂"}, {"drug_name": "natural products library", "company": "University of Oklahoma HSC", "org_type": "大学", "target": "5-LOX and mPGES1", "modality": "other", "importance_level": "低", "total_score": 37.5, "institution_score": 35, "track_score": 45, "milestone_score": 30, "field_heat_score": 40, "bonus_score": 0, "brief_reason": "针对5-LOX和mPGES1炎症靶点从天然产物库中筛选潜在抑制剂，用于CRC炎症干预，但当前仅为体外筛选阶段。大学机构+早期HTS筛选，缺乏明确药物候选物和临床进展，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/2864", "id": "dlXM_5wBX1NQZOEH-LO6", "source_drug_name": "natural products library", "title": "Screening of natural products library against 5-lipoxygenase (5-LOX) and mPGES1 proinflammatory targets for CRC interception", "abstract_text": "Colorectal Cancer (CRC) remains the leading cause of cancer-related mortality worldwide. Inflammation is a key hallmark of many cancers, including CRC. Pro-inflammatory lipid mediators play a key role, while COX-2 inhibiting NSAIDs are promising, their chronic use is linked with unwanted side-effects. In this context, mechanistic studies suggest that targeting microsomal prostaglandin synthase-1 (mPGES-1) and 5-lipoxygenase (5-LOX) with natural products (NP) presents a valuable opportunity to intercept CRC and mitigate those side effects. Here we aimed to perform high-throughput screening (HTS) of NCI NPs library (~500,000 semi-purified fractions) to identify potential inhibitors of 5-LOX and mPGES1; and further validate the purified compounds using secondary assays. To establish the enzyme activity inhibitory assays, first we developed a stable Human Embryonic Kidney (HEK) 293 cell lines with mPGES-1 and 5-LOX overexpression as well as 5-LOX overexpressing insect cells. Proteins expression was confirmed using western blotting. Lysates from human 5-LOX expressed in Sf9 insect cells and HEK-293 cells, were used to generate an assay format in 384-well microplates suitable for HTS. In this assay format, lysates are preincubated with inhibitors for 20 minutes, stimulated with arachidonic acid (AA) for 5 minutes. The production of free radicals, as a result of the conversion of AA to 5HPETE and LTA4 by 5-LOX activity, is detected upon the addition of 2’,7’-dichlorodihydrofluorescein diacetate (H2DCFDA). The non-fluorescent H2DCFDA when oxidized by the free radicals, generates a highly fluorescent compound, which can be measured to quantify enzyme activity. The reaction was stopped after 15 minutes upon the addition of acetonitrile. Finally, enzyme activity was calculated by measuring “total relative fluorescence units (RFU) at 485-nm excitation and 530-nm emission spectra. The assay has been optimized using a final volume of 15ul and has a Z’ Factor score of 0.65 and a S/B of 3.5 in 384-well microplates. The 5-LOX activity was completely inhibited by 20uM NDGA, a known inhibitor of 5-LOX. Additionally, a pre-plated NCI library of semi-purified NP fractions (5mg/ml stock in DMSO) has been assessed to validate the assay and identify potential fractions that demonstrate 5-LOX inhibitory activity. The fractions with the most promising activity based on this evaluation will be presented at the meeting. We have also optimized the mPGES1 activity assay using HEK293 cell line overexpressing COX2 and mPGES-1. In this assay format, treatment with AA results in elevated levels of PGE2, as detected in a PGE2 HTRF assay. In summary, these optimized assays will be employed for large scale robotic HTS of NCI NP library to discover and develop safer inhibitors of proinflammatory targets mPGES1 and 5-LOX for intercepting inflammation associated cancers. (Funded by NCI-UG3CA290310-01).", "source_company": "University of Oklahoma HSC", "source_org_type": "大学", "row_number": 55, "target_meta": "PTGES1", "MOA_meta": "其他"}, {"drug_name": "dimethylthexyl siloxytecan", "company": "Aspiring Scholars Directed Research Program", "org_type": "研究机构", "target": "Topoisomerase I", "modality": "inhibitor", "importance_level": "低", "total_score": 37.5, "institution_score": 20, "track_score": 60, "milestone_score": 35, "field_heat_score": 50, "bonus_score": 3, "brief_reason": "药物为SN-38的硅基醚类似物，通过抑制Topoisomerase I发挥抗癌活性，并具有独特蓝色荧光特性用于实时成像追踪；机构为高中生科研培训项目（ASDRP），处于preclinical早期SAR阶段，无临床进展，综合研发价值有限。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6550", "id": "MFXM_5wBX1NQZOEH-LG5", "source_drug_name": "dimethylthexyl siloxytecan", "title": "Silyl ethers analogs of SN-38 with unique blue-fluorescent properties exhibit potent anti-cancer activity through topoisomerase I inhibition", "abstract_text": "Topoisomerase I inhibitors, such as deruxtecan and irinotecan, represent an important class of cell cycle inhibitors in the treatment of cancers. Among these, silylated topoisomerase inhibitors, including DB-67 and karenitecin, have exhibited increased antiproliferative potency. In this study, we prepared and evaluated the biological activity of four synthetic SN-38 analogs bearing the tert-butyldimethyl, tert-butyldiphenyl, triisopropyl, and dimethylthexyl siloxy groups, blocking a key metabolic site and imbuing bright blue-fluorescent properties in such compounds. When evaluated against colorectal, TN breast cancer, and ovarian, non-small cell lung, and liver cancer models, we observed comparable or greater antiproliferative activity. Our dimethylthexyl siloxytecan demonstrated the greatest potency among the four analogs, with a 96 hour IC50 of 6 nM in HCT-116 cells. Correspondingly, analysis by flow cytometry indicates that the siloxytecans, compared to their parent compounds, display comparable apoptotic activity and increased cell cycle G2 arrest. Uniquely, we demonstrate that the enhanced fluorescence of these compounds enables real-time, quantitative visualization of the dynamics and selectivity of intracellular uptake through fluorescence microscopy without the need for extensive sample preparation or installation of auxiliary fluorophores, with the dimethylthexyl siloxytecan displaying the greatest rate of cellular uptake. Additionally, quantification of relaxed and nicked DNA levels via cell-free biochemical studies suggests that these siloxytecans largely exhibit increased topoisomerase inhibition from SN-38. Further computer modeling studies validated that differences in potency and permeability were not attributed to the siloxytecans’ positioning within the Topoisomerase I-DNA binding pocket. This initial SAR is further supplemented by an evaluation of these compounds’ DMPK properties and metabolic stability, with an assessment of different in-vivo delivery strategies. Moreover, direct tissue injection of the siloxytecans has demonstrated exceptional tissue retention and durability, establishing the dimethylthexyl siloxytecan as a preclinical lead for in vivo evaluation. Collectively, these studies demonstrate improved intracellular delivery of topoisomerase inhibitors with the introduction of silicon-containing motifs and highlight the utility of these compounds for enhanced anticancer activity with unique lipophilicity and fluorescent properties that enable quantitative tracking of compound distribution in cancer cells, which is currently being investigated for in vivo activity in triple negative breast cancer studies.", "source_company": "Aspiring Scholars Directed Research Program", "source_org_type": "研究机构", "row_number": 178, "target_meta": "TOP1", "MOA_meta": "抑制剂"}, {"drug_name": "cytochalasin D", "company": "University of Sao Paulo", "org_type": "大学", "target": "actin cytoskeleton / F-actin", "modality": "other", "importance_level": "低", "total_score": 37.5, "institution_score": 25, "track_score": 40, "milestone_score": 45, "field_heat_score": 50, "bonus_score": 0, "brief_reason": "cytochalasin D为经典actin聚合抑制剂，主要靶向actin cytoskeleton/F-actin，破坏核F-actin以削弱GBM干细胞特性及DNA修复。大学机构+工具化合物性质+纯preclinical体外/体内数据导致总体评分较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/715", "id": "4VXM_5wBX1NQZOEH-LC5", "source_drug_name": "cytochalasin D", "title": "Actin cytoskeleton modulation reprograms resistant GBM spheroids and GSCs, enhancing response to IR and temozolomide in vitro and in vivo", "abstract_text": "Actin cytoskeleton regulate essential processes in cancer progression, including cell division, migration, invasion, and genomic stability. Nuclear F-actin has emerged as a critical regulator of DNA repair, chromatin organization, and transcription, representing a potential therapeutic target. Glioblastoma (GBM), a highly aggressive tumor with strong resistance to ionizing radiation (IR) and temozolomide (TMZ), frequently relies on GBM stem-like cells (GSCs) to sustain recurrence. GSCs exhibit enhanced DNA repair, and their stemness is influenced by pathways linked to actin dynamics. We investigated whether targeting actin polymerization sensitizes GBM to therapy by modulating DNA damage response (DDR) and GSC phenotypes. IR- and TMZ-resistant U87-MG cells generated through cyclic treatments were grown as 3D spheroids. Resistant spheroids showed increased proliferation, faster cell-cycle progression, elevated cell death within the core, and markedly enhanced self-renewal, supporting a stem-like tumorigenic profile. Interestingly, resistant cells exhibited distinct invasion patterns: IR-resistant were more invasive, whereas TMZ-resistant were more migratory, consistent with pFAK and vimentin immunoblotting, indicating distinct GSC-like subtypes within each resistant population. Strikingly, spheroid assembly in the presence of F-actin-disrupting drugs (cytochalasin D/B or latrunculin B) reduced therapy resistance and diminished tumorigenicity. Zebrafish xenotransplantation confirmed the aggressive proliferation, mortality rates, and metastatic dissemination of resistant cells, all of which were significantly reduced upon actin-targeting treatments, resulting in increased animal survival. RNA-seq, qPCR, immunoblotting, and immunofluorescence revealed upregulation of GSC markers in resistant spheroids, while actin disruption markedly reduced their expression. We propose that nuclear F-actin regulates transcriptional circuits that maintain stemness and therapy resistance. Consistently, resistant cells exhibited elevated nuclear actin which was dynamically modulated by genotoxic stress or pharmacological actin disruption. Ongoing chromatin-fraction proteomics aim to identify nuclear F-actin-associated proteins under damage conditions. Finally, in PDX GSC23 cells, inhibition of F-actin polymerization reduced stemness markers under self-renewal conditions and prevented serum-induced differentiation. Cytochalasin D enhanced sensitivity of GSC23 to IR and TMZ, reducing proliferation, viability, and tumorigenicity. Collectively, these findings reveal actin cytoskeleton regulation, particularly nuclear F-actin, as a vulnerability that can be therapeutically exploited to overcome GBM resistance, supporting actin-modulating compounds as promising adjuvants for GBM therapy.", "source_company": "University of Sao Paulo\nUniversity of São Paulo", "source_org_type": "大学", "row_number": 290, "target_meta": "F-actin", "MOA_meta": "其他"}, {"drug_name": "lentiviral-based hematopoietic stem cell platform", "company": "Northwestern University", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 37.5, "institution_score": 25, "track_score": 65, "milestone_score": 20, "field_heat_score": 50, "bonus_score": 0, "brief_reason": "基于慢病毒的造血干细胞平台用于胶质瘤免疫治疗中的巨噬细胞特异性表达，靶点和具体机制未披露。大学机构+早期概念性研究阶段导致总体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11524", "id": "clXM_5wBX1NQZOEH-LK6", "source_drug_name": "lentiviral-based hematopoietic stem cell platform", "title": "Lentiviral-based hematopoietic stem cell platform for macrophage-specific expression in glioma immunotherapy", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Northwestern University", "source_org_type": "大学", "row_number": 560, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "a novel oral G-quadruplex stabilizer", "company": "Hexin Biotech (Changchun) Limited", "org_type": "公司", "target": "G-quadruplex", "modality": "inhibitor", "importance_level": "低", "total_score": 37.5, "institution_score": 30, "track_score": 65, "milestone_score": 20, "field_heat_score": 50, "bonus_score": 0, "brief_reason": "药物为新型口服G-quadruplex稳定剂，针对DNA修复缺陷癌症包括脑转移，靶点为G-quadruplex本身，机制新颖但非热门主流靶点。研发机构Hexin Biotech (Changchun) Limited为非头部中国小型biotech公司，摘要被embargo且无披露具体开发阶段信息，整体preclinical早期热度较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11420", "id": "d1XM_5wBX1NQZOEH-LK6", "source_drug_name": "a novel oral G-quadruplex stabilizer", "title": "A novel oral G-quadruplex stabilizer for the treatment of DNA repair-deficient cancers, including brain metastases", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Hexin Biotech (Changchun) Limited", "source_org_type": "公司", "row_number": 563, "target_meta": "G4", "MOA_meta": "抑制剂"}, {"drug_name": "t-butyl carbonate podophyllotoxin analog", "company": "Aspiring Scholars Directed Research Program", "org_type": "研究机构", "target": "tubulin", "modality": "inhibitor", "importance_level": "低", "total_score": 37.5, "institution_score": 20, "track_score": 65, "milestone_score": 35, "field_heat_score": 50, "bonus_score": 0, "brief_reason": "该化合物为podophyllotoxin的C-4碳酸酯类似物，通过抑制tubulin聚合作用发挥抗有丝分裂活性。机构为研究项目性质、仅处于早期体外SAR研究阶段、无明确临床开发路径，导致整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/2856", "id": "Vp7ECZ0BZznHJdntvNYd", "source_drug_name": "t-butyl carbonate podophyllotoxin analog", "title": "C-4 analogs of podophyllotoxin inhibit tubulin polymerization: A generalizable platform for the discovery of antimitotic therapeutics for cancer", "abstract_text": "Antimitotic agents, such as podophyllotoxin and its derivatives, act through a ubiquitous mechanism of action by targeting the most fundamental mechanisms of cell division, and have demonstrated broad clinical potential as anticancer therapeutics. Given the pharmacological importance of the C-4 hydroxyl on podophyllotoxin, we sought to establish a structure-activity relationship between chemical modification and in vitro potency. We previously reported that increased C-4 sterics of podophyllotoxin esters have minimal effect on cell-free tubulin polymerization, yet decrease in vitro potency against human colon cancer cells. In this study, the antiproliferative activity of 26 novel carbonate, carbamate, and silyl ether podophyllotoxin analogs was evaluated for inhibition of in vitro cell viability, cell cycle arrest, cell-free tubulin polymerization, immunofluorescence imaging, and docking models. In human and murine colorectal cancer (HCT-116, HT-29, CT-26), lung cancer (A549, Calu-1), triple-negative breast cancer (MDA-MB-231 P), liver carcinoma (Hep G2), ovarian adenocarcinoma (SK-OV-3), and embryonic kidney cells (HEK-293), the carbonate analogs exhibited greater antiproliferative activity when compared to their carbamate counterparts, while the silyl ether analogs performed the poorest. Most notably, the t-butyl carbonate exhibited the most potent activity with IC50 at or below single digit nanomolar ranges, while the carbamates exhibited IC50 values greater than 42 nM. Correspondingly, the most potent analogs also exhibited potent cell cycle G2/M arrest by flow cytometry, with t-butyl carbonate causing arrest to the greatest percentage (69.2%), affirming tubulin inhibition as the primary mechanism of action. However, those differences were not reflected in the cell-free biochemical assay, where the best carbonates and carbamates showed similar percentages of tubulin inhibition (85.78% and 85.28% respectively), and no correlation was observed between C-4 substituent and tubulin inhibition. Additionally, in silico modeling revealed a minimal difference in each analog’s binding affinity, providing further evidence that C-4 functionalization does not directly alter a compound’s ability to bind to tubulin. Collectively, our results suggest that absolute binding to tubulin is not the primary determinant of biological activity for C-4 analogs of podophyllotoxin across a broad panel of cancer cell lines, and that the impact of structural changes at C-4 on biological potency is agnostic to logP and steric bulk. Altogether, the structure-activity relationship described enables future development of podophyllotoxin-based antimitotic agents for cancer.", "source_company": "Aspiring Scholars Directed Research Program", "source_org_type": "研究机构", "row_number": 651, "target_meta": "microtubule", "MOA_meta": "抑制剂"}, {"drug_name": "AI-10-104", "company": "Universidad de Buenos Aires", "org_type": "大学", "target": "RUNX", "modality": "inhibitor", "importance_level": "低", "total_score": 37.5, "institution_score": 25, "track_score": 55, "milestone_score": 35, "field_heat_score": 45, "bonus_score": 0, "brief_reason": "AI-10-104为RUNX转录活性抑制剂，靶向TNBC中RUNX促进肿瘤异质性、干性及化疗耐药的机制。大学机构preclinical细胞水平研究，赛道非热门且无明确临床里程碑，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4358", "id": "pVXM_5wBX1NQZOEH-LO6", "source_drug_name": "AI-10-104", "title": "Targeting RUNX transcriptional activity reduces tumor heterogeneity and aggressiveness in triple-negative breast cancer", "abstract_text": "Triple-negative breast cancer (TNBC) is a highly aggressive disease, characterized by early relapse and enriched with cancer stem cells (CSCs), contributing to chemoresistance and metastasis. Our research focuses on RUNXs role in TNBC aggressiveness, cell migration promotion and regulation of gene expression. We reported that RUNX1 influences chemoresistance in androgen-responsive TNBC cell lines and Ferrari (2016) showed its correlation with poor prognosis in TNBC patients. Lv (2024) showed that RUNX2 is also implicated in chemoresistance, and Halperin (2022) established that RUNX1 is upregulated in cancer-associated fibroblasts of breast cancer patients and predicts poor disease outcomes. Our study explores how inhibiting RUNX transcriptional activity impacts TNBC cell lines aggressiveness and drug response. Using RUNX-CBFβ commercial inhibitors (AI-10-104 and AI-10-49) we observed significant reduction in viability and migration, and increased apoptosis in MDA-MB-231 and -468 cell lines. In a forced-suspended cell model, inhibiting RUNX transcriptional activity decreased mRNA levels of crucial genes for CSC maintenance. In MDA-MB-231 cells, RUNX inhibition completely hindered mammosphere formation. RUNX1 mRNA and protein expression increased in doxorubicin (Doxo) and paclitaxel (Px) treated cells. RUNX inhibition enhances drug toxicity, reducing viability and boosting apoptosis. Combined AI-10-104 and Doxo significantly reduced the number of mammospheres even more than Doxo alone, while AI-10-104 restored Px sensitivity in Px-resistant cells. By flow cytometry we observed that RUNX inhibition significantly downregulates PD-L1 expression, suggesting an important role in tumor immune escape. Furthermore, RUNX1 inhibition alters mitophagy-related gene expression and induces mitochondrial fragmentation in SUM-159PT cells. Finally, by transcriptomic analysis (cDNA-seq) using long-read oxford nanopore technology, we compare the expression profiles of adherent with forced-suspension growing MDA-MB-468 cells, treated with AI-10-104, and gain insights into the underlying mechanisms. Analyses have identified 10 genes including metabolic, stress, drug resistance’ genes, among others, whose expression is differentially affected by RUNX transcriptional inhibition depending on the culture model. These findings point to potentially distinct RUNX-dependent regulatory mechanisms across tumor subpopulations, which are currently under our investigation. In summary, our results suggest that RUNXs play a critical role in generating chemoresistant TNBC cells by influencing intracellular heterogeneity and immune surveillance cancer hallmarks.", "source_company": "Universidad de Buenos Aires", "source_org_type": "大学", "row_number": 761, "target_meta": "not available", "MOA_meta": "抑制剂"}, {"drug_name": "SIRT1 inhibitor", "company": "The Sixth Affiliated Hospital, Sun Yat-sen University", "org_type": "医院", "target": "SIRT1", "modality": "inhibitor", "importance_level": "低", "total_score": 37.5, "institution_score": 25, "track_score": 45, "milestone_score": 40, "field_heat_score": 50, "bonus_score": 0, "brief_reason": "SIRT1抑制剂通过调控DDX5去乙酰化及色氨酸代谢正反馈抑制放疗诱导的cGAS/STING通路和TLS形成，促进放射免疫治疗耐药。机构为医院而非药企、仅动物模型及机制研究、无临床阶段数据导致整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9486", "id": "vlXM_5wBX1NQZOEH-LO6", "source_drug_name": "SIRT1 inhibitor", "title": "SIRT1 inhibits T cell infiltration and tertiary lymphoid structure formation to promote radioimmunotherapy resistance", "abstract_text": "Background: Microsatellite stable (MSS) rectal cancer is intrinsically resistant to immunotherapy. Although radiotherapy is often combined with immune checkpoint inhibitor (ICIs) to enhance immunotherapy responses, many immunologically cold tumors remain unresponsive.\nMethods: The radiotherapy-induced antitumor immunity effect of SIRT1 inhibition was assessed in murine models. The mechanisms of SIRT1 and DDX5 in tumor immune escape with radiotherapy were determined in vitro and in vivo. The synergistic effects of SIRT1 inhibitor or aspirin plus radiotherapy with PD-1 blockade were also investigated.\nResults: We observed a significant increase in electron transport chain activity, acetyl-CoA level, and pan-acetylation level in patients achieving pathologic complete response (pCR) following immunotherapy administered after radiotherapy. Through transcriptomic screening and in vivo experiments, we found that SIRT1, a key executor in regulating protein acetylation, restricted the immunostimulatory effects of radiotherapy. Mechanistically, SIRT1 deacetylates DDX5, promoting its unwinding of irradiation-induced R-loop and inhibiting the accumulation of cytoplasmic RNA: DNA hybrids, thereby suppressing the cGAS/STING pathway and T cell infiltration. Interestingly, we found that radiotherapy forced the tryptophan-SIRT1-SLC36A4 positive feedback, further enhancing SIRT1 activity and competitively uptaking tryptophan in the microenvironment, thereby inhibiting TLS formation and leading to poor efficacy of radioimmunotherapy. Finally, we discovered that both SIRT1 inhibitor and aspirin plus radiotherapy converts ICI-unresponsive rectal cancer into immunogenic tumors that are hyper-sensitive to ICI.\nConclusions: SIRT1 is a potential biomarker and therapeutic target to overcome radioimmunotherapy resistance.", "source_company": "The Sixth Affiliated Hospital, Sun Yat-sen University", "source_org_type": "医院", "row_number": 782, "target_meta": "SIRT1", "MOA_meta": "抑制剂"}, {"drug_name": "monoclonal antibodies targeting TRPV6 and CXCR4", "company": "University of Lille", "org_type": "大学", "target": "TRPV6/CXCR4", "modality": "monoclonal antibody", "importance_level": "低", "total_score": 37.5, "institution_score": 25, "track_score": 45, "milestone_score": 45, "field_heat_score": 50, "bonus_score": 2, "brief_reason": "药物为靶向TRPV6和CXCR4的双单抗，针对CRPC骨转移的新机制轴，但仅大学机构开展的体内外proof-of-concept研究，尚未披露临床阶段。打分较低主要因非头部机构、靶点非当前最热门赛道且开发早期。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6203", "id": "2lXM_5wBX1NQZOEH-LO6", "source_drug_name": "monoclonal antibodies targeting TRPV6 and CXCR4", "title": "TRPV6/CXCR4 signaling complexes as therapeutic targets to prevent osteoblastic bone metastasis in castration-resistant prostate cancer", "abstract_text": "Background: Bone metastasis is a leading cause of morbidity and mortality in advanced prostate cancer, affecting up to 90% of patients with castration-resistant prostate cancer (CRPC). Around 85% of these lesions are osteoblastic. The calcium channel TRPV6 is absent in healthy prostate tissue but produced de novo during malignant transformation, with higher expression in advanced and castration-resistant stages. TRPV6 regulates calcium influx and downstream signalling pathways that promote proliferation, invasion and survival. Previous studies have shown that TRPV6 promotes epithelial-mesenchymal transition (EMT), migration, invasion and metastatic dissemination, particularly to bone, and forms functional complexes with the chemokine receptor CXCR4, a key mediator of tumour cell homing to bone. Here, we investigated how the TRPV6-CXCR4 axis contributes to osteoblastic bone metastases and whether its pharmacological inhibition could be therapeutically beneficial.\nMethods: TRPV6 and CXCR4 expression and co-localization were analyzed in human prostate cancer tissues and bone metastases. Functional assays using TRPV6-overexpressing or TRPV6-knockout cells evaluated osteoblast-mediated migration, invasion and activation. In vivo studies assessed the effect of targeting TRPV6 and CXCR4, individually or in combination, with monoclonal antibodies on metastatic burden and bone lesion phenotype.\nResults: TRPV6 expression strongly correlated with tumor aggressiveness and metastatic progression in clinical samples. TRPV6 activation triggered CaMK2 phosphorylation, NF-κB nuclear translocation and upregulation of EMT-associated transcription factors (Twist, Snail, Slug), enhancing migratory and invasive phenotypes. Concurrently, TRPV6 promoted stable CXCR4-TRPV6 complex formation, amplifying pro-metastatic signalling. In co-culture assays, TRPV6-expressing cells markedly increased osteoblast activation markers (ALP, RUNX2, OPN) and matrix mineralisation, indicating functional tumour-osteoblast crosstalk driving osteoblastic niche formation. In vivo, TRPV6-positive tumors primarily produced osteoblastic bone lesions, and dual targeting of TRPV6 and CXCR4 reduced the incidence of metastases, attenuated pathological bone remodeling, and prolonged overall survival.\nConclusions: These results highlight the TRPV6-CXCR4 complex as a key regulator of osteoblastic bone metastasis in CRPC. Dual targeting of TRPV6 and CXCR4 provides a proof-of-concept therapeutic strategy to prevent or limit bone metastasis in prostate cancer.", "source_company": "University of Lille", "source_org_type": "大学", "row_number": 804, "target_meta": "TRPV6,CXCR4", "MOA_meta": "单抗"}, {"drug_name": "PAK4 inhibitor", "company": "Sanford Burnham Prebys Med. Discovery Inst.", "org_type": "研究机构", "target": "PAK4", "modality": "inhibitor", "importance_level": "低", "total_score": 37.5, "institution_score": 30, "track_score": 65, "milestone_score": 20, "field_heat_score": 50, "bonus_score": 0, "brief_reason": "靶点为PAK4，通过抑制诱导病毒模拟增强肿瘤免疫，机制具有一定免疫治疗潜力。机构为研究机构而非商业公司、摘要仍处于embargo无具体开发阶段或里程碑信息、preclinical性质导致整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11500", "id": "R1XM_5wBX1NQZOEH-LS6", "source_drug_name": "PAK4 inhibitor", "title": "PAK4 inhibition enhances tumor immunity by inducing viral mimicry", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Sanford Burnham Prebys Med. Discovery Inst.", "source_org_type": "研究机构", "row_number": 881, "target_meta": "PAK4", "MOA_meta": "抑制剂"}, {"drug_name": "GABAB receptor inhibitors", "company": "Henry Ford Health System", "org_type": "医院", "target": "GABAB receptor", "modality": "inhibitor", "importance_level": "低", "total_score": 37.5, "institution_score": 25, "track_score": 45, "milestone_score": 45, "field_heat_score": 50, "bonus_score": 2, "brief_reason": "靶向GABAB受体抑制剂阻断CAFs介导的胰腺癌免疫抑制，机制新颖但仅preclinical阶段。医院机构+早期数据导致综合评分较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/7448", "id": "0p7M_5wBZznHJdnt_W3O", "source_drug_name": "GABAB receptor inhibitors", "title": "Targeting GABA signaling in cancer associated fibroblasts to reduce immunosuppression in pancreatic cancer", "abstract_text": "Pancreatic ductal adenocarcinoma (PDAC) is a devasting disease with few therapeuticoptions. This is due, in large part, to the expansion of the non-tumor cellular compartmentknown as the stroma. Cancer-associated fibroblasts (CAFs) are one of the major celltypes that populate the stroma of PDAC tumors and are extremely immunosuppressivebecause they produce large amounts of cytokines, growth factors and metabolites. Thus,understanding how CAFs impart severe immunosuppression in the tumormicroenvironment is critical to make PDAC amenable to immunotherapies. Using a novel3D culturing method, our data support the notion that PDAC CAFs produce the glutamatemetabolite and inhibitory neurotransmitter gamma aminobutyric acid (GABA), de novo,and we detected GABA (~27µM) in tumor interstitial fluid (TIF) isolated from patient tissue(10 patients). Surprisingly, CAFs lacked expression of glutamate decarboxylase, thecanonical enzyme responsible for converting glutamate into GABA, which led us toexplore alternative, non-canonical pathways for GABA synthesis. We found that CAFsderived from patient PDAC tumors expressed the enzymes of the non-canonicalsynthesis pathway (ODC1, DAO, ALDH1A1 and ALDH9A1), and to a greater degreewhen compared to normal fibroblasts. In parallel, we demonstrated that, by exploringparacrine signaling, GABA treatment of CAFs resulted in changes in expression of p-p70,p-JNK, p-MTOR and p-AKT proteins, key signaling hubs involved in overcomingmetabolic stress in PDAC. In addition, GABA treatment increased the production of pro-tumor cytokines, such as TGFβ, IL8, and IL6, by CAFs. In preclinical orthotopic murinetumor models of PDAC, inhibition of GABA synthesis through ALDH1A1, and GABAsignaling through GABAB receptor inhibitors, reduced tumor burden, increased influx ofanti-tumor T and NK cells, and blocked production of pro-tumor cytokines in tumorexplants. Translationally, we have acquired patient matched plasma, TIF, and tissue from10 patients, and will compare their metabolic, immune, and spatial transcriptomic profileswith well annotated clinical parameters, in order to develop improved diagnostic tests.Overall, we have uncovered a novel signaling circuit driven by GABA that plays a role incontrolling the extremely immunosuppressive PDAC microenvironment.", "source_company": "Henry Ford Health System\nHenry Ford Health", "source_org_type": "医院", "row_number": 1101, "target_meta": "GABAB receptor", "MOA_meta": "抑制剂"}, {"drug_name": "tricarbonylperrhenato(bathophen)rhenium(I)", "company": "Mayo Clinic Florida", "org_type": "医院", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 37.5, "institution_score": 35, "track_score": 45, "milestone_score": 30, "field_heat_score": 40, "bonus_score": 0, "brief_reason": "该化合物为有机金属铼配合物，通过下调pMEK和pP38调控MAPK通路发挥抗PDAC作用，但靶点未明确披露。机构为医院学术型、处于体外细胞系研究早期阶段、铼类抗癌化合物非热门主流赛道，故综合评分较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6549", "id": "X57M_5wBZznHJdnt_W7P", "source_drug_name": "tricarbonylperrhenato(bathophen)rhenium(I)", "title": "Anticancer efficacy of tricarbonylperrhenato(bathophen)rhenium(I) organometallic compound in pancreatic ductal adenocarcinoma", "abstract_text": "Organometallic rhenium compounds have become powerful anticancer agents that show possibilities as a substitute for traditional platinum-based medications. While platinum-based chemotherapeutics like FOLFIRINOX and cisplatin are frequently used to treat pancreatic ductal adenocarcinoma (PDAC), they have a number of side effects, such as ototoxicity, neurotoxicity, nephrotoxicity, and peripheral neuropathy. Hepatotoxicity, cardiotoxicity, gastrointestinal toxicity, cytopenias, anaphylaxis, pain, alopecia, anorexia, cachexia, and asthenia are other commonly reported adverse effects.\nHowever, ligands based on rhenium have been shown to preferentially cause cytotoxicity in cancer cells while avoiding harm to healthy cells. This suggests that rhenium could be a safer and more effective cancer treatment option. Different rhenium compounds with different ligands have been produced by Mandal et al. for a range of medicinal uses. In this work, we assessed the therapeutic potential of tricarbonylperrhenato(bathophen)rhenium(I) (PR-6) in PDAC. The cytotoxic effects and IC₅₀ value of PR-6 were assessed in the metastatic pancreatic cancer cell line AsPC-1 using the MTS assay. The IC₅₀ value for PR-6 in AsPC-1 cells was determined to be 5.85 µM. PR-6 treatment significantly inhibited cell growth, migration, and survival at the IC₅₀ concentration, with a post-treatment survival rate of 2.3 ± 3.97%. Furthermore, PR-6 treatment led to the downregulation of phosphorylated MEK (pMEK) and phosphorylated P38 (pP38) protein expression, indicating its modulatory effect on the MAPK signaling pathway. According to our research, PR-6 has a great therapeutic promise for treating pancreatic cancer and efficiently alters the tumor microenvironment in PDAC cells.", "source_company": "Mayo Clinic Florida", "source_org_type": "医院", "row_number": 1186, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "immune checkpoint blockade", "company": "St. John's Research Institute", "org_type": "研究机构", "target": "未披露", "modality": "inhibitor", "importance_level": "低", "total_score": 37, "institution_score": 20, "track_score": 75, "milestone_score": 25, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "摘要讨论免疫检查点阻断（ICB）在绝经前三阴性乳腺癌中的抵抗机制，但未披露具体药物或靶点，仅为机制研究。机构为研究机构且无明确药物开发里程碑，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10821", "id": "Np7M_5wBZznHJdnt_W7O", "source_drug_name": "immune checkpoint blockade", "title": "Low hypoxia microenvironment and impaired T cell maturation drive immunotherapy resistance in premenopausal triple negative breast cancer", "abstract_text": "Purpose: Triple-negative breast cancer (TNBC) often show limited response to immune checkpoint blockade (ICB) therapy, but the mechanisms underlying this resistance remain unclear. This study aimed to investigate how menopausal status associated changes in the tumor microenvironment influence antitumor immunity, particularly T-cell differentiation and activation, and how these factors may contribute to ICB resistance.\nMethods: Spatial transcriptomic profiling (NanoString GeoMx DSP) was performed on 19 TNBC tumors across 59 tumor and immune regions. These data were integrated with publicly available bulk RNA seq datasets from METABRIC and SCAN-B, as well as single-cell RNA seq data (GSE176078) including pre and postmenopausal TNBC samples. Gene Set Enrichment Analysis (GSEA) was used to identify pathway-level differences, and T-cell subtypes from the single-cell dataset were assessed for distribution and functional state. Findings were further investigated using immunotherapy response data from the I-SPY2 clinical trial.\nResults: Premenopausal TNBC tumors showed consistent downregulation of hypoxia and angiogenesis pathways across both spatial and bulk transcriptomic datasets. These pathways were positively correlated (r = 0.61, p = 5.8e-05) and associated with reduced immune signaling. Single-cell profiling showed an enrichment of naïve and progenitor-like CD8⁺ T cells in premenopausal tumors, lacking exhaustion markers such as PDCD1, TOX, and TIGIT. In contrast, postmenopausal tumors contained more cytotoxic CD8⁺ T cells expressing granzyme and perforin, indicative of enhanced effector activity. Although premenopausal tumors had higher proportions of M1 macrophages and follicular helper T cells, these populations did not appear to drive effective cytotoxic responses. Importantly, the hypoxia-low transcriptional profile of premenopausal TNBC resembled that of ICB non-responders in the I-SPY2 trial.\nConclusions: Reduced hypoxia-related signaling and impaired maturation of cytotoxic T-cell responses may contribute to weak antitumor immunity and poor ICB efficacy in premenopausal TNBC. These findings point to the need for tailored therapeutic strategies to improve immunotherapy responses in premenopausal TNBC.", "source_company": "St. John's Research Institute", "source_org_type": "研究机构", "row_number": 98, "target_meta": "not available", "MOA_meta": "抑制剂"}, {"drug_name": "AURKA inhibitor", "company": "OSU James Cancer Hospital", "org_type": "医院", "target": "AURKA", "modality": "inhibitor", "importance_level": "低", "total_score": 37, "institution_score": 30, "track_score": 65, "milestone_score": 20, "field_heat_score": 40, "bonus_score": 0, "brief_reason": "药物为AURKA抑制剂，通过诱导pro-immunogenic senescence激活cGAS-STING信号以改善肿瘤微环境并协同免疫治疗，但摘要被embargo未披露具体化合物或数据。公司为医院/学术机构而非商业药企，处于preclinical概念验证阶段，无明确里程碑进展。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11529", "id": "L57ECZ0BZznHJdntvNYd", "source_drug_name": "AURKA inhibitor", "title": "Senescence as an immune tolerance breaker: Inhibitors of mitotic kinases TTK (Mps1) and AURKA induce pro-immunogenic senescence that primes the tumor microenvironment for immunotherapy via cGAS-STING signaling", "abstract_text": "Abstract is embargoed at this time.", "source_company": "OSU James Cancer Hospital", "source_org_type": "医院", "row_number": 332, "target_meta": "AURKA", "MOA_meta": "抑制剂"}, {"drug_name": "ζ-Stat", "company": "University of South Florida", "org_type": "大学", "target": "PKC-ζ", "modality": "inhibitor", "importance_level": "低", "total_score": 37, "institution_score": 30, "track_score": 40, "milestone_score": 40, "field_heat_score": 50, "bonus_score": 0, "brief_reason": "ζ-Stat为选择性PKC-ζ小分子抑制剂，通过抑制PKC-ζ/Cx43信号诱导GBM细胞衰老和周期阻滞。机构为大学、处于体外细胞系研究阶段、PKC-ζ在肿瘤中非热门靶点且无临床进展，导致整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3429", "id": "7lXM_5wBX1NQZOEH-LG6", "source_drug_name": "ζ-Stat", "title": "ζ-Stat inhibits glioblastoma multiforme progression by targeting PKC-ζ/Cx43 signaling and inducing senescence", "abstract_text": "Glioblastoma multiforme (GBM) is a grade IV astrocytic tumor and the most aggressive form of brain cancer, marked by poor prognosis, complex vascular networks, and genomic heterogeneity. PI3K/AKT (Phosphoinositide 3-kinase/Protein Kinase B) signaling and the atypical protein kinase C isoform PKC-ζ, play essential roles in GBM cell proliferation, migration, and resistance to therapy. In addition, PKC-ζ regulates Connexin 43 (Cx43), a gap junction protein that influences cell communication, cytoskeletal organization, and tumor cell motility. This study investigated the effects of ζ-Stat (8-hydroxy-1,3,6-naphthalenetrisulfonic acid), a selective PKC-ζ inhibitor, on GBM cell lines. Treatment with ζ-Stat significantly reduced proliferation by approximately 40% in T98G cells (80 μM) and 30% in U87MG cells (40 μM) (p ≤ 0.001). Co-immunoprecipitation confirmed a strong association between PKC-ζ and Cx43 in both cell lines. Western blot analysis demonstrated that treatment with ζ-Stat reduced the levels of PKC-ζ and Cx43. As a result of PKC-ζ/Cx43 inhibition, PI3K/AKT signaling was downregulated in T98G cells. In addition, ζ-Stat induced cell cycle arrest, with increased expression of p21, p27, and PTEN, while inducing cellular senescence, as indicated by elevated β-galactosidase activity. Furthermore, ζ-Stat affected epithelial-mesenchymal transition (EMT), reducing the migratory potential of the cells through inhibition of vimentin expression. These findings highlight ζ-Stat as a promising therapeutic candidate for overcoming chemoresistance and improving treatment outcomes in glioblastoma.", "source_company": "University of South Florida", "source_org_type": "大学", "row_number": 475, "target_meta": "PKCζ", "MOA_meta": "抑制剂"}, {"drug_name": "ζ-Stat", "company": "University Of South Florida", "org_type": "大学", "target": "PKC-ζ", "modality": "inhibitor", "importance_level": "低", "total_score": 37, "institution_score": 30, "track_score": 40, "milestone_score": 40, "field_heat_score": 50, "bonus_score": 0, "brief_reason": "ζ-Stat为PKC-ζ选择性小分子抑制剂，在儿科胶质母细胞瘤SF188细胞系中显示抑制增殖和诱导凋亡作用。机构为大学，处于体外preclinical早期研究阶段，aPKC靶点在肿瘤中非主流热门赛道，故整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4429", "id": "ZlXM_5wBX1NQZOEH-LK6", "source_drug_name": "ζ-Stat", "title": "Inhibition in the proliferation of pediatric glioblastoma facilitated with atypical protein kinase c inhibitors", "abstract_text": "Pediatric glioblastoma (pGBM) is an aggressive brain tumor with a five-year survival rate of approximately 5%. Current therapeutic options are limited, primarily due to poor blood-brain barrier penetration of available drugs. Atypical Protein Kinase C (aPKC) isoforms, Protein Kinase C- iota (PKC-ι) and Protein Kinase C- zeta (PKC-ζ), play crucial roles in tumor cell proliferation and survival. In this study, we investigated the effects of ICA-1S [5-amino-1-((1R,2S,3S,4R)-2,3-dihydroxy-4-methylcyclopentyl)-1H-imidazole-4-carboxamide], a selective PKC-ι inhibitor, and ζ-Stat [8-hydroxy-1,3,6-naphthalenetrisulfonic acid], a PKC-ζ inhibitor, on pediatric glioblastoma SF188 cells. SF188 cells (50,000/well) were seeded in 6-well plates and treated with varying concentrations of ICA-1S and ζ-Stat for three days. On the fourth day, cell viability was determined to generate a dose-response curve. ICA-1S showed maximal inhibition at 75 μM, while ζ-Stat decreased proliferation by approximately 50% at 20 μM. These results suggest that both PKC-ι and PKC-ζ contribute to SF188 cell proliferation. To explore the molecular mechanisms underlying this inhibition, protein lysates from treated and untreated cells were analyzed via Sodium Dodecyl Sulfate-Polyacrylamide Gel Electrophoresis (SDS-PAGE) and Western blotting. Both ICA-1S and ζ-Stat treatments resulted in downregulation of PKC-ι and PKC-ζ protein expression compared to control samples. Furthermore, expression of the apoptotic marker Caspase-3 was found to be decreased in drug-treated cells, suggesting activation of apoptotic signaling following inhibition of aPKCs. These findings indicate that selective inhibition of aPKCs suppresses proliferation and induces apoptosis in pediatric glioblastoma cells. Ongoing and future studies will employ immunoprecipitation, immunofluorescence, and WST assays to elucidate downstream signaling pathways and validate ICA-1S and ζ-Stat as potential therapeutic candidates for pediatric glioblastoma.", "source_company": "University Of South Florida\nUniversity of South Florida", "source_org_type": "大学", "row_number": 551, "target_meta": "PKCζ", "MOA_meta": "抑制剂"}, {"drug_name": "kinase inhibitor ADCs", "company": "San Carlos", "org_type": "未知", "target": "未披露", "modality": "ADC", "importance_level": "低", "total_score": 37, "institution_score": 20, "track_score": 85, "milestone_score": 10, "field_heat_score": 30, "bonus_score": 0, "brief_reason": "药品为kinase inhibitor类ADC，属于ADC热门赛道且靶向激酶抑制剂机制有一定创新性，但机构San Carlos未知且非头部公司。摘要无任何具体信息，无靶点披露、无开发阶段细节，导致里程碑和机构分极低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11911", "id": "EVXM_5wBX1NQZOEH-LS6", "source_drug_name": "kinase inhibitor ADCs", "title": "Kinase inhibitor ADCs: Leveraging tumor-intrinsic vulnerabilities for the treatment of hematological and solid Tumors", "abstract_text": "There is no abstract associated with this presentation.", "source_company": "San Carlos", "source_org_type": "未知", "row_number": 844, "target_meta": "not available", "MOA_meta": "抗体偶联药物"}, {"drug_name": "probe 2", "company": "Inha University", "org_type": "大学", "target": "heparan sulfate", "modality": "荧光显像剂", "importance_level": "低", "total_score": 37, "institution_score": 25, "track_score": 45, "milestone_score": 45, "field_heat_score": 40, "bonus_score": 3, "brief_reason": "probe 2为细胞表面锚定比率型荧光探针，选择性结合heparan sulfate并实现活细胞成像，同时显著抑制癌细胞迁移。大学早期工具化合物性质，缺乏临床开发机构和热门赛道支撑，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6155", "id": "JlXM_5wBX1NQZOEH-LS6", "source_drug_name": "probe 2", "title": "Cell surface anchored ratiometric probes for heparan sulfate enable live cell bioimaging and suppression of cancer cell migraion", "abstract_text": "Heparan sulfate (HS) proteoglycans are essential molecular components of the cell surface glycocalyx that play critical roles in tumor growth, cell migration, and cancer invasion. Despite their biological significance, the development of fluorescent probes capable of selectively and quantitatively visualizing HS in live cells has been highly challenging due to poor water solubility, limited cell-surface retention, and insufficient molecular selectivity. Here, we synthesized a rationally designed peptide-based fluorescent probe (probe 2) that selectively binds to HS on live cell membranes. This probe exhibits prolonged membrane localization and produces a distinct ratiometric fluorescence response. Under physiological conditions, probe 2 achieves stable anchoring on the cell surface and enables quantitative detection of HS through red-shifted emissions upon aggregation. Importantly, this probe allows real-time visualization of HS downregulation in live cells following siRNA-mediated gene silencing or chemical inhibition of HS biosynthesis. Moreover, probe 2 significantly inhibited cell migration and wound healing in vitro, suggesting that HS modulation by the probe may influence tumor-associated cellular behaviors. Collectively, this study introduces a new class of membrane-anchored fluorescent probes that enable dynamic and quantitative imaging of HS in live cells. These findings suggest that probe 2 is both a diagnostic imaging tool for heparan sulfate and a molecular modulator of HS-related cancer biology, with potential implications for cancer research and therapeutic development.", "source_company": "Inha University", "source_org_type": "大学", "row_number": 858, "target_meta": "HSGAG", "MOA_meta": "荧光显像剂"}, {"drug_name": "REPYR-SC1", "company": "University of Miami Miller School of Medicine", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 37, "institution_score": 30, "track_score": 40, "milestone_score": 40, "field_heat_score": 50, "bonus_score": 0, "brief_reason": "REPYR-SC1为新型大麻提取物，靶点和具体机制未明确披露，可能涉及cannabinoid相关免疫调节和抗增殖作用。大学机构preclinical体外数据，创新性有限，赛道非热门，综合重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/2868", "id": "iVXM_5wBX1NQZOEH-LS6", "source_drug_name": "REPYR-SC1", "title": "Dose-dependent anti-proliferative activity of a bioactive hemp-derived extract REPYR-SC1 against prostate cancer", "abstract_text": "In the US approximately 1 in 8 men are diagnosed with prostate cancer, and metastatic cases account for the majority of prostate cancer-related mortality. Prostatic cancer is the second leading cause of cancer death in men, harboring a 32% 5-year survival rate. Current treatments utilize a combination of androgen deprivation therapy, androgen signaling receptor inhibitors and chemotherapy. Despite these improvements, castration-resistance and chemotherapy resistance remain a significant obstacle to sustained remission and signify a need for novel therapeutic approaches. Immunotherapies and the discovery of new anti-neoplastic agents are current modalities of considerable interest. We explore the use of REPYR-SC1, a novel hemp extract, as an anti-cancer, immunomodulatory agent following the pre-clinical evidence demonstrating anti-neoplastic efficacy of cannabinoid derivatives and their potential immunoactivity. C4 cells were used to model prostate cancer, HPrEC prostate epithelial cells as a non-cancerous control, and CTLL-2 cytotoxic T lymphocytes were chosen as a quantifiable measure of immunomodulatory capability. REPYR-SC1 was administered at 0, 0.1, 0.5, 1, and 5 μL/mL and cultured with C4, HPrEC and CTLL-2 cells for 24 and 48 hours. Morphological assessment was performed by light microscopy, pre- and post-treatment. Subsequent to this manual cell counts were performed pre-and post-treatment, followed by trypan blue exclusion assay. Only viable cells were included in the cell count. REPYR-SC1 produced a significant dose- and time-dependent reduction in proliferation (p<0.001) in prostate cancer C4 cells and CTLL-2 cells. At a dose of 1 and 5 μL/mL at the 24- and 48-hour mark, full inhibition of proliferation was observed in C4 cells. HPrEC cells showed minimal susceptibility with 20% inhibition observed for 5 μL/mL at 48 hours. CTLL-2 cells showed significant susceptibility with complete inhibition of proliferation observed at a dose of 1 and 5 µL/mL at 48 hours. REPYR-SC1 exhibited measurable immunomodulatory effects against T-lymphocytes in vitro, and selective anti-neoplastic activity versus prostate cancer cells. In conclusion, REPYR-SC1 demonstrated evidence of potential for prostate cancer inhibition and warrants further investigation.", "source_company": "University of Miami Miller School of Medicine", "source_org_type": "大学", "row_number": 929, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "HDAC inhibitor", "company": "Salk Institute for Biological Studies", "org_type": "研究机构", "target": "HDAC", "modality": "inhibitor", "importance_level": "低", "total_score": 37, "institution_score": 30, "track_score": 60, "milestone_score": 20, "field_heat_score": 50, "bonus_score": 0, "brief_reason": "靶点为HDAC类组蛋白去乙酰化酶抑制剂，主要机制是通过重分布转录机制使胰腺癌对DNA损伤治疗敏感，但摘要被禁运未披露具体药物或更深入数据。机构为学术研究机构而非药企、开发阶段为preclinical机制研究、无明确里程碑，综合热度一般导致总分较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11560", "id": "Op7M_5wBZznHJdnt_W7O", "source_drug_name": "HDAC inhibitor", "title": "HDAC inhibition sensitizes pancreatic cancer to DNA-damaging therapies via genome-wide redistribution of transcriptional machinery", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Salk Institute for Biological Studies", "source_org_type": "研究机构", "row_number": 1164, "target_meta": "HDAC", "MOA_meta": "抑制剂"}, {"drug_name": "αPDL1-800", "company": "Mass Eye and Ear", "org_type": "医院", "target": "PD-L1", "modality": "荧光显像剂", "importance_level": "低", "total_score": 36.5, "institution_score": 25, "track_score": 45, "milestone_score": 40, "field_heat_score": 50, "bonus_score": 0, "brief_reason": "αPDL1-800为抗PD-L1抗体偶联IRDye 800CW的荧光显像剂，用于活体FLT成像定量PD-L1表达；机构为医院非商业研发、modality为成像剂非治疗热门赛道、仅preclinical工具性质导致总体评分较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6286", "id": "m1XM_5wBX1NQZOEH-LG6", "source_drug_name": "αPDL1-800", "title": "In-vivo fluorescence lifetime tomography for detection and quantification of programmed death ligand-1", "abstract_text": "Programmed death ligand-1 (PD-L1) is the only clinically approved predictive biomarker for cancer immunotherapy; however, its expression is highly heterogeneous and routinely assessed by ex vivo immunohistochemistry. To enable spatially resolved, noninvasive PD-L1 quantification, we employed fluorescence lifetime (FLT) tomography with a normalization strategy designed to account for nonspecific probe uptake. C57BL/6 mice bearing orthotopic RIL-175 liver tumors (n=10) were injected with αPDL1-800 (anti-PD-L1 antibody conjugated to IRDye 800CW). 48 hours post-injection, we performed in vivo time-domain FLT imaging with co-registered CT, followed by in situ FLT imaging and western blotting to validate PD-L1 expression. Bi-exponential fitting of the time-resolved fluorescence data yielded spatial maps of FLT (τ) and amplitude (a). The top 10% of FLTs within the tumor were averaged to define the bound lifetime component (τ_b), while the mean FLT in the normal liver was considered as the FLT of the unbound component (τ_u). Amplitudes of bound (a_b) and unbound (a_u) probes were extracted and segmented into tumor (a_b,T; a_u,T) and normal (a_b,N; a_u,N) ROIs. Among four normalization strategies tested, one correcting for background cross-talk (a_b,T - a_u,T) and normalizing by total uptake (a_b,N - a_u,N) showed the strongest correlation with PD-L1 expression (R² = 0.77). 3D reconstructions using asymptotic time-domain analysis confirmed accurate tumor localization and size. FLT tomography distinguished bound from unbound αPDL1-800 and enabled quantitative assessment of PD-L1 expression in deep-seated tumors. The normalization method enabled accurate quantification of PD-L1 expression across tumors, supporting the utility of FLT imaging for preclinical immunotherapy evaluation and biomarker-guided therapy monitoring.", "source_company": "Mass Eye and Ear", "source_org_type": "医院", "row_number": 417, "target_meta": "PDL1", "MOA_meta": "荧光显像剂"}, {"drug_name": "Cucurbitacin B", "company": "Zhengzhou University", "org_type": "大学", "target": "PPAT", "modality": "inhibitor", "importance_level": "低", "total_score": 36.5, "institution_score": 25, "track_score": 45, "milestone_score": 45, "field_heat_score": 40, "bonus_score": 2, "brief_reason": "Cucurbitacin B通过诱导TRIM38介导的PPAT多聚泛素化降解，特异性抑制从头嘌呤合成途径关键限速酶PPAT，阻断ESCC肿瘤生长并增敏放疗。该药来自大学机构，处于机制验证阶段（体内外+PDX/CDX模型），赛道非热门，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8877", "id": "IlXM_5wBX1NQZOEH-LO6", "source_drug_name": "Cucurbitacin B", "title": "Inhibition of de novo purine biosynthesis via PPAT targeting by cucurbitacin B restrains esophageal squamous cell carcinoma growth", "abstract_text": "Background: The de novo purine biosynthesis (DNPB) pathway plays a critical role in the malignant progression of tumors. However, its specific contribution to esophageal squamous cell carcinoma (ESCC) growth, radioresistance, and response to targeted therapies remains poorly understood.\nMethods: In this study, the underlying metabolic change of ESCC were analyzed by untargeted metabolomics and single-cell RNA sequencing data analyses. The expression and function of PPAT were further evaluated through immunohistochemistry (IHC) and lentivirus-mediated gene manipulation. Additionally, patient-derived xenograft (PDX) and cell-derived xenograft (CDX) models were utilized to assess the role of PPAT and its inhibitor in ESCC tumor growth and radioresistance.\nResults: In this study, we identified phosphoribosyl pyrophosphate amidotransferase (PPAT), a key rate-limiting enzyme in the DNPB pathway, as a critical modulator of ESCC malignancy. We demonstrated that PPAT promotes the production of energy-related nucleotides, including AMP, GMP, ADP, GDP, ATP, and GTP, thereby fueling ESCC tumor growth in vitro and in vivo. Moreover, we found that Cucurbitacin B (CuB) specifically targets PPAT and induces its polyubiquitin-mediated degradation via the E3 ligase TRIM38, leading to suppression of the DNPB pathway and inhibition of tumor growth. Importantly, CuB also functions as a radiosensitizer, significantly enhancing the therapeutic efficacy of radiotherapy in ESCC.\nConclusions: Our findings reveal that targeting PPAT represents a promising therapeutic strategy to suppress ESCC progression and enhance the efficacy of radiotherapy.", "source_company": "Zhengzhou University\nHenan Medical College, Zhengzhou University", "source_org_type": "大学", "row_number": 672, "target_meta": "PPAT", "MOA_meta": "抑制剂"}, {"drug_name": "molybdenum disulfide nanoparticles", "company": "Texas A&M University", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 36.5, "institution_score": 25, "track_score": 40, "milestone_score": 45, "field_heat_score": 50, "bonus_score": 3, "brief_reason": "MoS2纳米颗粒作为无药物EMT抑制剂，通过抑制integrin活性及TGFβ信号通路展现抗转移潜力，但靶点未明确披露。大学机构、非主流modality、仅动物水平数据导致整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6386", "id": "u1XM_5wBX1NQZOEH-LO6", "source_drug_name": "molybdenum disulfide nanoparticles", "title": "Regulating epithelial-to-mesenchymal transcription-driven metastatic capacity with molybdenum disulfide (MoS2) nanoparticles", "abstract_text": "Epithelial-to-mesenchymal transition (EMT) is the process by which stationery, tightly connected epithelial cells transform into more mobile, flexible phenotype. This plays a significant role in allowing cancer cells to detach from the original tumor, invade surrounding tissues and spread throughout the body. While EMT plays a role in significant physiological functions such as wound healing, the development of a mesenchymal phenotype within the tumor microenvironment is detrimental, promoting cancer cell escape into circulation and subsequent development of the pre-metastatic niche. EMT is a major contributor to the risk and progression of metastatic cancers and targeting and blocking EMT presents a potential therapeutic intervention for preventing the development of metastases. Here, we introduce molybdenum disulfide (MoS2) nanoparticles as a potential drug-free inhibitor of EMT, which is advantageous over traditional chemotherapy-type drugs due to lack of adverse off-target effects in distant tissues. This study investigates the impact of MoS2 nanoparticles on epithelial-to-mesenchymal transition in highly metastatic triple-negative breast cancer both in vitro and in vivo. Treatment of MoS2 nanoparticles decreased migratory capacity of in vitro and in vivo models of ER+ and triple negative breast cancer, demonstrating the anti-metastatic motility property of MoS2. In vitro, MoS2-treated breast cancer cells observe decrease in focal adhesion proteins and genes associated with cellular motility. Furthermore, cells show decrease in TGFβ signaling and expression of EMT markers after 72h of exposure, indicating that MoS2 nanoparticles inhibited EMT progression mediated through cellular motility and TGFβ signaling. This effect was further demonstrated with functional 3D mammosphere assays, which indicated reduced mammosphere formation and size. Similarly, clonogenicity was significantly reduced in cells following treatment with MoS2 nanoparticles. In vivo, direct injection of MoS2 into 4T1 mouse mammary tumors significantly decreased primary tumor growth and burden as well as the number of metastatic foci in the lung. Our work demonstrates that MoS2 nanoparticles inhibit integrin activity as well as the TGFβ signaling cascade pathway, blocking the transition of cells to a mesenchymal-like phenotype. These findings suggest that MoS2 nanoparticles hold promise for drug-free cancer therapeutic applications in reducing metastatic potential.", "source_company": "Texas A&M University", "source_org_type": "大学", "row_number": 779, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "guided antimicrobial peptides (gAMPs)", "company": "Baylor University", "org_type": "大学", "target": "Fusobacterium nucleatum", "modality": "other", "importance_level": "低", "total_score": 36.5, "institution_score": 25, "track_score": 45, "milestone_score": 35, "field_heat_score": 50, "bonus_score": 3, "brief_reason": "gAMPs为针对CRC相关Fusobacterium nucleatum的引导型抗菌肽，由生物工程益生菌表达递送，机制新颖但属于preclinical概念验证阶段。大学机构+非主流热门赛道+早期体外/共培养数据导致整体重要性较低，仅因选择性机制有少量加分。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/954", "id": "uZ3ECZ0B4z9FlvORyiZD", "source_drug_name": "guided antimicrobial peptides (gAMPs)", "title": "Precision therapy against CRC associated Fusobacterium nucleatum using bioengineered probiotics expressing guided antimicrobial peptides (gAMPs)", "abstract_text": "Colorectal cancer (CRC) is a leading cause of cancer-related mortality, with Fusobacterium nucleatum (F. nucleatum) identified as a key contributor to its progression. This study explores a novel therapy that targets this pathogen by using a bioengineered probiotic that expresses guided antimicrobial peptides (gAMPs) to selectively inhibit F. nucleatum. in this study, Lactococcus lactis MG1363 was engineered to express gAMPs derived from Ovispirin and Cathelin-related peptide SCF, linked to a Statherin-derived guide peptide that binds specifically to the F. nucleatum membrane porin FomA. The bacteria expressed the AMP/gAMP under the induction of the PNisA promoter by nisin and secreted it via the extracellular secretion signal usp45. The resultant synthetic peptides and probiotics were assayed for antimicrobial activity against the targeted F. nucleatum and other non-target bacteria. Biofilm inhibition and growth kinetic assays were performed with synthetic peptides in vitro or the probiotic in co-culture with a polymicrobial community. We saw that statherin-derived guide peptide enhanced the binding affinity to F. nucleatum, significantly increasing attachment compared to control peptides. In vitro assays revealed that both unguided and guided AMPs effectively inhibited biofilm formation in F. nucleatum, with gAMPs showing reduced toxicity against non-target bacteria. The gAMPs were more effective in modulating growth kinetics, exhibiting selective toxicity towards F. nucleatum at lower concentrations. Co-culture experiments in a simulated human gut microbiome showed the gAMP probiotic maintained microbial diversity while effectively reducing F. nucleatum abundance. Quantitative PCR and 16S rRNA sequencing confirmed that gAMP treatment preserved the richness of the microbiota, contrasting with significant dysbiosis observed in control samples. These findings support the potential of engineered probiotics as a therapeutic approach that targets CRC-associated F. nucleatum.", "source_company": "Baylor University", "source_org_type": "大学", "row_number": 1189, "target_meta": "F. nucleatum", "MOA_meta": "其他"}, {"drug_name": "CPCCOEt", "company": "Meharry Medical College", "org_type": "大学", "target": "mGluR1", "modality": "inhibitor", "importance_level": "低", "total_score": 36.5, "institution_score": 25, "track_score": 45, "milestone_score": 35, "field_heat_score": 50, "bonus_score": 0, "brief_reason": "CPCCOEt为mGluR1抑制剂，摘要显示其为T细胞激活关键glutamatergic checkpoint，与TCR整合增强CD8⁺ T细胞抗肿瘤功能。机构为大学非商业研发，处于早期机制研究阶段，无药物开发推进，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1313", "id": "gp7M_5wBZznHJdnt_W7P", "source_drug_name": "CPCCOEt", "title": "The metabotropic Glutamate receptor-1 is a glutamatergic checkpoint that integrates with TCR to augment anti-tumor CD8⁺ T cell activation, metabolism and effector function", "abstract_text": "Background: Glutamate receptors (GluRs), classically linked to neuronal signaling, are also recognized as key immunomodulators. T cell activation requires precise coordination of TCR-driven signaling microclusters and calcium-dependent pathways that shape T cell effector function. Emerging evidence shows that glutamatergic cues influence T cell metabolism, activation, and fate, yet their role within TCR signaling remains poorly defined. Here, we show how GluR-TCR interactions govern CD8⁺ T cell activation and function, particularly within the metabolic and functional constraints of the tumor microenvironment.\nMethods: Tumors and lymphoid tissue single-cell suspensions were analyzed for the expression of ionotropic (GluA3, NR1, NR2B) and metabotropic (mGluR1, mGluR5) receptors on CD4⁺ and CD8⁺ TILs by flow cytometry. CD8⁺ T cells were activated with anti-CD3/CD28 or PMA/ionomycin ± IL-2 in the presence or absence of NBQX (GluA3) and CPCCOEt (mGluR1) inhibitors. Expression of glutamate transporters, viability, and extracellular glutamate were assessed by fluorometric assays. CPCCOEt-treated cells were analyzed for mGluR1-TCR colocalization and phosphorylation of TCR-signaling proteins by confocal microscopy and flow cytometry. Metabolic activity was measured by Seahorse XF96 (OCR/ECAR). Intracellular Ca²⁺ dynamics were evaluated using Fura-2 AM ratiometric imaging. CD8⁺ T cell proliferation was assessed by CFSE, and cytotoxicity was tested in vitro and in vivo using a pulmonary metastasis model; activated CD8⁺ T cells ± antagonists were transferred retro-orbitally.\nResults: We found that mGluR1 and GluA3 are expressed at higher levels in T cells compared with other immune cell lineages, and their expression increases during CD8⁺ T cell activation. Conversely, pharmacologic inhibition with CPCCOEt significantly impaired CD8⁺ T cell activation, disrupting mGluR1 colocalization with the TCR-Vβ8.1 in the cell membrane and reducing phosphorylation of key proteins involved in TCR-driven signaling, metabolic pathways, inducing a pronounced dysregulation of Ca²⁺ flux. Functionally, CPCCOEt-treated CD8⁺ T cells showed a reduction in proliferation to levels resembling naïve T cells and a marked decrease in cytotoxic activity. In vivo, these impairments translated into an increased burden of secondary metastatic pulmonary nodules, highlighting the essential role of mGluR1 signaling in sustaining effector CD8⁺ T cell function and antitumor immunity.\nConclusion: These findings identify mGluR1 as a critical glutamatergic checkpoint that integrates with the TCR to augment CD8⁺ T cell activation, metabolism, and effector function. Its disruption collapses signaling strength, Ca²⁺ responses, and cytotoxic competence, revealing a potential target to boost T cell potency in solid tumor microenvironments.", "source_company": "Meharry Medical College", "source_org_type": "大学", "row_number": 1213, "target_meta": "mGluR1", "MOA_meta": "抑制剂"}, {"drug_name": "LA3IK", "company": "UNT Health Science Center", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 36.3, "institution_score": 25, "track_score": 40, "milestone_score": 45, "field_heat_score": 35, "bonus_score": 3, "brief_reason": "LA3IK为L-肽抑制剂（D-异构体D-LA3IK更稳定），针对EGF诱导的转录级联，但具体分子靶点未披露。大学机构基础研究、preclinical阶段、机制为肽类抑制且有D-异构体优化亮点，但整体热度和开发阶段较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1040", "id": "tVXM_5wBX1NQZOEH-LS6", "source_drug_name": "LA3IK", "title": "Temporal profiling of the EGF-induced transcriptional cascade in PC3 prostate cancer cells reveals biphasic oncogenic reprogramming", "abstract_text": "The Epidermal Growth Factor (EGF) signaling pathway is a potent driver of prostate cancer progression, yet a comprehensive, time-resolved understanding of its transcriptional dynamics remains incomplete. This study employed temporal RNA-sequencing on PC3 prostate cancer cells to profile the transcriptomic landscape at critical intervals (0, 30 min, 1 h, 6 h) following EGF stimulation. Our analysis reveals a biphasic oncogenic reprogramming. The initial phase, evident within 30-60 minutes, is characterized by a rapid surge of immediate-early genes (FOS, JUN, EGR family) and the coordinated activation of pathways promoting cell migration, inflammation (NF-κB, IL-17), and early signaling (MAPK). This is followed by a distinct secondary phase at 6 hours, where the transcriptome pivots to strongly enrich processes dedicated to sustained growth and survival, including cell cycle progression, DNA replication, and the PI3K-AKT-mTOR signaling axis. Having established this kinetic map, we demonstrate that the previously characterized L-peptide inhibitor, LA3IK, effectively suppresses this program. Co-treatment with EGF and LA3IK for 6 hours resulted in significant inhibition of genes across these critical pathways, including PI3K-AKT, MAPK, and cell cycle. To overcome the proteolytic limitations of the L-peptide, we then employed its D-enantiomer, D-LA3IK, which yielded superior results, driving a more profound and comprehensive reversal of the EGF-induced transcriptome and exhibiting enhanced efficacy in functional assays. This work delineates the phased transcriptional cascade orchestrated by EGF and establishes targeted peptide inhibition, particularly with the stable D-isomer, as a potent strategy to disrupt this oncogenic program.", "source_company": "UNT Health Science Center", "source_org_type": "大学", "row_number": 965, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "anti-mouse CSF1R", "company": "Univ of Arizona College of Med – Tucson", "org_type": "大学", "target": "CSF1R", "modality": "inhibitor", "importance_level": "低", "total_score": 36, "institution_score": 20, "track_score": 60, "milestone_score": 40, "field_heat_score": 50, "bonus_score": 0, "brief_reason": "药物为针对CSF1R的抗体抑制剂，靶向TAMs以抑制OSCC小鼠模型肿瘤生长，机制明确但仅为preclinical工具性研究。机构为大学，开发阶段早期且无产业化推进，导致总体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10556", "id": "m57M_5wBZznHJdnt_W3O", "source_drug_name": "anti-mouse CSF1R", "title": "Tumor-associated macrophages promote oral squamous cell carcinoma development", "abstract_text": "Oral squamous cell carcinoma (OSCC), the most common oral malignancy, is characterized by poor prognosis, risk factors of tobacco and alcohol, and epithelial-specific mutations. Within the tumor microenvironment (TME) of OSCC, tumor-associated macrophages (TAMs) are key immune cells recruited to the tumor site and can be polarized into different phenotypes with either pro-inflammatory or anti-inflammatory functions. Therefore, there is a significant need to understand the role of TAMs in the OSCC microenvironment and the interaction between TAMs and cancer cells that may impact OSCC’s aggressiveness and therapy resistance. Our lab has established cell lines from mouse oral tumors generated by activation of epithelial-specific mutations in mouse oral epithelium using both genetic and carcinogenic systems. Using these models, we employed an orthotopic and immunocompetent approach to study the specific functions of TAMs on the OSCC TME with surrounding lymphoid organs and highly dense vascularity. After orthotopic implantation, these cell lines developed oral tumors with high levels of TAM infiltration. To determine the role of TAMs in oral tumor development we depleted macrophages systemically with an anti-mouse Colony Stimulating Factor-1 Receptor (CSF1R). Results showed a significantly decreased tumor growth in mice injected with anti-CSF1R compared to untreated mice. Immunohistochemistry confirmed the loss of TAMs from the tumors treated with anti-CSF1R. Ongoing studies focus on investigating how macrophages remodel the tumor immune microenvironment of OSCC and modulate the malignant properties of oral cancer cells. We envision that these studies will help develop prevention and therapeutic approaches by targeting the pro-tumorigenic activities of TAMs in OSCC.", "source_company": "Univ of Arizona College of Med – Tucson\nUniversity of Arizona", "source_org_type": "大学", "row_number": 1056, "target_meta": "CSF-1R", "MOA_meta": "抑制剂"}, {"drug_name": "Veratridine", "company": "University of South Dakota", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 35.8, "institution_score": 25, "track_score": 45, "milestone_score": 35, "field_heat_score": 50, "bonus_score": 3, "brief_reason": "Veratridine通过转录上调UBXN2A间接降解Rictor和mortalin影响mTORC2通路，但药物本身无明确直接靶点。大学早期重定位研究，preclinical阶段，机制有一定新颖性但整体开发价值和热度有限。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8782", "id": "LlXM_5wBX1NQZOEH-LG5", "source_drug_name": "Veratridine", "title": "Repurposing veratridine, a previously used antihypertensive supplement, for effective treatment of metastatic colorectal cancer", "abstract_text": "Despite significant advances in improving colorectal cancer (CRC) survival over the past decade, therapeutic challenges persist due to the rapid spread of primary tumors. The rising incidence of early-onset colorectal cancer (patients under age 50) across all ethnicities has created another major health concern, as these patients are often diagnosed with advanced, metastatic disease, leading to higher mortality rates. This highlights the urgent need to develop more effective targeted therapies to fight metastatic CRC. The mTORC2 signaling pathway plays a key tumorigenic role in CRC by driving processes such as metastasis and drug resistance. The objective of this study is to develop a selective mTORC2 inhibitor that prevents tumor growth and metastasis without harming normal cells. This project aims to advance Veratridine (VTD), a small plant-derived molecule that transcriptionally upregulates UBXN2A, a colon-specific tumor-suppressor protein. UBXN2A's E3 ubiquitin ligase partners enable it to specifically target and degrade mitochondrial HSP70 (mortalin) oncoprotein and Rictor protein in the mTORC2 pathway. This study demonstrates the dual-action mechanisms of the VTD-UBXN2A axis in patient-derived xenograft (PDX) cell lines. Acute and sub-chronic VTD treatment using both two-dimensional (2D) and three-dimensional (3D) PDX cells, assessed using real-time cell analysis via xCELLigence and Cytation visualizing technologies, revealed that VTD effectively suppresses cell migration and metastatic features of human CRC cells. Our genetic and pharmacological tools have established a platform for repurposing Veratridine, a previously used anti-hypertensive supplement, into a new generation of anti-metastatic drugs that function mechanistically through a ubiquitin-like protein, while simultaneously providing greater safety and therapeutic efficacy in patients with metastatic CRC.", "source_company": "University of South Dakota", "source_org_type": "大学", "row_number": 341, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "MG-KKR-5-268", "company": "Florida A&M University", "org_type": "大学", "target": "未披露", "modality": "inhibitor", "importance_level": "低", "total_score": 35.8, "institution_score": 25, "track_score": 45, "milestone_score": 35, "field_heat_score": 40, "bonus_score": 3, "brief_reason": "MG-KKR-5-268为新型四氢异喹啉类小分子化合物，通过非微管机制在G2/M期阻滞TNBC细胞增殖并阻止3D肿瘤球固化，具有潜在新型细胞周期调控机制。机构为大学、仍处于早期优化阶段且靶点/确切机制未明确披露，导致整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8809", "id": "81XM_5wBX1NQZOEH-LG6", "source_drug_name": "MG-KKR-5-268", "title": "A novel potent tetrahydroisoquinoline analog: A cytostatic taxol-like agent", "abstract_text": "In 2024, according to the American Chemical Society, approximately 310,720 new cases of invasive breast cancer will be diagnosed among US women, and 42,250 women will die from breast cancer. Triple-negative breast cancer (TNBC) represents 10 to 15% of all breast cancers. TNBC has fewer treatment options than other types of invasive breast cancer, which limits the effectiveness of targeted hormonal or HER2-directed therapies and is heavily reliant on cytostatic agents such as taxanes and vinca alkaloids. The limited efficacy and increasing side effects of these agents highlight the urgent need for alternative small molecules that block proliferation through novel but less toxic mechanisms. We previously synthesized and characterized tetrahydroisoquinoline (THIQ) derivatives, identifying MG-KKR-4-53 as a highly soluble, non-toxic, and cytostatic agent that halts TNBC cell proliferation without functioning as a spindle poison. Instead, it arrests the cell cycle at G2/M phase. Continuing our research, we further developed a more potent analogue, MG-KRR-5-268, and performed comprehensive in-silico ADMET and cheminformatics analyses, comparing it with Taxol, vinblastine, and MG-KKR-4-53, which map directly to well-known predictive toxicology and metabolism databases/models powered by ADMETlab, SwissADME, and CYP/clearance data. The compounds of interest were synthesized in our lab using O-mesitylene sulfonylhydroxylamine as an aminating agent. Reaction of the Isoquinoliniumamino salt with substituted acid chlorides in anhydrous tetrahydrofuran gave stable ylides. Reduction of the ylides using sodium borohydride gave the target THIQ compounds, which were characterized by NMR and elemental analysis. Compound 3-fluoro-N-(7-hydroxy-3,4-dihydroisoquinolin-2(1H)-yl)-4-methylbenzamide (MG-KKR-5-268) showed significant cytostatic activity with IC50 of 169 nM representing a 7.1-fold increase over MG-KKR-4-53 (IC50 = 1.2 µM). Paclitaxel (250 nM) solidified tumor spheroids at submicromolar concentrations, whereas vinblastine (123nM) caused their disassembly. MG-KRR-5-268 (257nM) exhibited strong prevention of spheroid compaction across submicromolar doses, phenocopying the disassembly of the vinblastine phenotype through a non-tubulin mechanism, compared to the other THIQ analogs. These findings highlighted MG-KRR-5-268 acted as the most potent compound with a novel capacity to prevent 3D tumor solidification through transcriptome reprogramming rather than microtubule binding.", "source_company": "Florida A&M University", "source_org_type": "大学", "row_number": 479, "target_meta": "not available", "MOA_meta": "抑制剂"}, {"drug_name": "fHBs-T84scFv-Fc", "company": "Chang Gung University", "org_type": "大学", "target": "CEACAM5", "modality": "other", "importance_level": "低", "total_score": 35.8, "institution_score": 25, "track_score": 45, "milestone_score": 35, "field_heat_score": 40, "bonus_score": 3, "brief_reason": "该融合蛋白通过CEA（CEACAM5）靶向递送HBsAg片段，利用HBV疫苗免疫的CD8+ T细胞杀伤肿瘤细胞，属于创新的免疫劫持策略。大学机构+非热门modality+纯preclinical概念验证阶段导致总体评分较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5120", "id": "SlXM_5wBX1NQZOEH-LK6", "source_drug_name": "fHBs-T84scFv-Fc", "title": "Utilization of HBV-vaccinated immunity to suppress tumor progression via targeted delivery of HBsAg to CEA-positive colorectal cancer", "abstract_text": "Limited antigen recognition hampers the anti-tumor efficacy of CD8⁺ T cells. We hypothesized that vaccinated immunity against hepatitis B virus (HBV) in individuals could be harnessed to target hepatitis B surface antigen (HBsAg)-expressed tumor cells, thereby suppressing tumor progression. We aimed to validate the proposed concept and to develop a tumor-targeting agent that delivers HBsAg to colorectal tumor cells via carcinoembryonic antigen (CEA)-targeted antibodies. We generated HBsAg-overexpressed CT26 colorectal tumor cells and utilized HBV-vaccinated BALB/c mice to evaluate the proposed concept. A fusion protein comprising a fragment of HBsAg (fHBs, amino acids 103-170) and a single-chain variable fragment (scFv) against CEACAM5 (CEA), linked to a Fc domain (fHBs-T84scFv-Fc), was constructed to deliver HBsAg into tumor cells for immune recognition and tumor suppression. We found that HBV-vaccinated mice exhibited strong anti-HBsAg responses and significantly suppressed HBsAg-overexpressed CT26 tumor growth, accompanied by increased CD3⁺ and CD8⁺ T cell infiltration in tumor tissues. CEACAM5 was identified as a colorectal tumor-specific receptor exhibiting internalization. We consequently demonstrated that the created anti-tumor reagent fHBs-T84scFv-Fc effectively bound tumor cells and inhibited growth of CEACAM5-positive MC38 tumors in the HBV-vaccinated mice. Meanwhile, enhanced infiltration of CD3⁺ and CD8⁺ T cells was observed in the tumor tissues under fHBs-T84scFv-Fc treatment. We demonstrated a novel strategy by utilizing HBV-vaccinated immunity for colorectal tumor suppression via CEA-targeted HBsAg delivery. This study suggests that the anti-HBV immunity containing anti-HBsAg CD8+ T cells can be utilized to suppress a range of tumors using HBsAg-antibody conjugates by targeting the tumor-specific internalizing receptors.", "source_company": "Chang Gung University", "source_org_type": "大学", "row_number": 534, "target_meta": "CEACAM5", "MOA_meta": "其他"}, {"drug_name": "31c", "company": "The University of Texas at El Paso", "org_type": "大学", "target": "PHD2, HDAC", "modality": "inhibitor", "importance_level": "低", "total_score": 35.8, "institution_score": 25, "track_score": 45, "milestone_score": 35, "field_heat_score": 40, "bonus_score": 3, "brief_reason": "31c为新型双靶点PHD2-HDAC抑制剂，主要用于保护顺铂+贝伐单抗引起的肾毒性，同时保留抗宫颈癌疗效。研发机构为大学，处于动物模型验证阶段，赛道非热门，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5530", "id": "HlXM_5wBX1NQZOEH-LO6", "source_drug_name": "31c", "title": "Dual PHD2-HDAC inhibitor 31c prevents cisplatin-bevacizumab nephrotoxicity and preserves antitumor efficacy in cervical cancer", "abstract_text": "Cisplatin-based chemotherapy combined with bevacizumab (CB) remains the standard first-line treatment for advanced or recurrent cervical cancer, integrating cytotoxic and anti-angiogenic mechanisms to improve clinical outcomes. However, treatment success is frequently undermined by dose-dependent nephrotoxicity caused by cisplatin and bevacizumab-induced vascular alterations. Thus, strategies capable of safeguarding renal function without attenuating antitumor activity are urgently needed to optimize treatment durability and patient survival. We previously developed 31c, a novel dual inhibitor of prolyl hydroxylase domain-containing protein 2 (PHD2) and histone deacetylases (HDACs), as a nephroprotective agent. Therefore, we evaluated the nephroprotective potential of 31c in a HeLa xenograft mouse model. Mice were treated with cisplatin, bevacizumab, or their combination, with or without 31c. Tumor growth kinetics and body weight were monitored to assess therapeutic response and systemic toxicity. Renal function was examined through blood urea nitrogen (BUN), serum creatinine (Scr), and erythropoietin (EPO) levels. Kidney tissues underwent histopathological evaluation using hematoxylin and eosin (H&E) and Masson’s trichrome staining to quantify tubular injury and fibrosis. RNA sequencing (RNA-seq) of kidney samples identified transcriptomic alterations, and immunofluorescence staining validated renal injury markers lipocalin-2 (Lcn2/NGAL) and kidney injury molecule-1 (Havcr1/KIM-1). Co-administration with 31c preserved the antitumor efficacy of the CB regimen, yielding tumor inhibition comparable to CB alone. Notably, 31c markedly reduced renal toxicity. Mice receiving CB alone displayed significant increases in BUN and Scr levels, extensive tubular degeneration, and marked collagen accumulation, hallmarks of acute renal injury and fibrosis. In contrast, 31c significantly reduced these pathological changes and maintained normal tubular structure. Transcriptomic profiling revealed distinct clustering among treatment groups, with 31c partially reversing CB-induced transcriptional dysregulation. Among the most upregulated genes in CB group, Lcn2 and Havcr1 were significantly suppressed by31c, consistent with immunofluorescence validation. The dual PHD2-HDAC inhibitor 31c confers robust nephroprotection against cisplatin-bevacizumab-induced renal injury without compromising antitumor activity. This integrated protective strategy highlights a promising approach to enhance the safety, tolerability, and continuity of platinum-anti-angiogenic therapies. By preserving renal integrity, 31c may support sustained treatment intensity and prolonged therapeutic benefit in patients with advanced cervical cancer and potentially other malignancies treated with similar regimens.", "source_company": "The University of Texas at El Paso", "source_org_type": "大学", "row_number": 671, "target_meta": "PHD2,HDAC", "MOA_meta": "抑制剂"}, {"drug_name": "RqGem", "company": "Jeonbuk National University", "org_type": "大学", "target": "未披露", "modality": "mutual prodrug", "importance_level": "低", "total_score": 35.8, "institution_score": 25, "track_score": 45, "milestone_score": 35, "field_heat_score": 40, "bonus_score": 3, "brief_reason": "RqGem为GSH响应型gemcitabine与atRA互连前药，主要通过GSH耗竭、氧化应激增强及Pin1下调实现协同抗癌，但靶点未明确披露。大学机构+preclinical阶段+创新递送形式但非热门modality导致整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6567", "id": "MFXM_5wBX1NQZOEH-LS6", "source_drug_name": "RqGem", "title": "Targeted co-delivery of gemcitabine and atRA via a GSH-responsive mutual prodrug enhances cytotoxicity through redox imbalance and Pin1 inhibition", "abstract_text": "Combination therapy offers strong potential to enhance anticancer efficacy, yet its success depends on the concurrent and targeted delivery of multiple agents. To address this challenge, we designed a self-assembling trimeric mutual prodrug, RqGem, which covalently links gemcitabine (GEM) and all-trans retinoic acid (atRA) through a glutathione (GSH)-depleting linker. This architecture enables excipients-free nanoassembly, achieving 100% drug loading and ensuring simultaneous delivery of both agents. RqGem nanoassemblies remained stable under physiological conditions and underwent esterase-mediated activation, releasing GEM and atRA along with a quinone methide intermediate that rapidly depletes intracellular GSH. This GSH depletion-driven redox modulation potentiated the cytotoxic mechanisms of both drugs by elevating oxidative stress and sensitizing cells to DNA damage and differentiation cues.The multiple and synergistic therapeutic actions of RqGem nanoassemblies were evaluated using cell culture and mouse models. RqGem nanoassemblies demonstrated significantly greater cytotoxicity, enhanced cellular uptake, and stronger apoptosis induction than the equivalent mixture of free GEM and atRA, reflecting robust synergy between atRA-mediated signaling modulation and GEM-induced DNA damage. The combined actions of self-assembly, 100% drug loading, concurrent drug release, and redox-dependent sensitization collectively contributed to the high potency of RqGem. Given that the role of atRA in targeting Pin1, a peptidyl-prolyl isomerase overexpressed in cancers and associated with poor prognosis, we further evaluated the impact of RqGem on Pin1 expression. Western blot analyses in AsPC-1 and CFPAC-1 pancreatic cancer cells showed marked Pin1 downregulation following RqGem treatment, supporting its dual mechanism of GEM delivery and atRA-mediated oncogenic pathway inhibition. Ongoing studies in orthotopic pancreatic tumor models aim to define the signaling pathways underlying RqGem-driven Pin1 suppression and its contribution to treatment synergy. Collectively, these findings establish RqGem as a rationally engineered, self-synergistic mutual prodrug that integrates drug self-delivery, controlled activation, and redox regulation to achieve potent and targeted anticancer activity. This platform holds strong translational promise for combination therapy in pancreatic cancer and beyond.", "source_company": "Jeonbuk National University", "source_org_type": "大学", "row_number": 866, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "FDA-approved drugs", "company": "Virginia Tech", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 35.5, "institution_score": 25, "track_score": 40, "milestone_score": 35, "field_heat_score": 60, "bonus_score": 0, "brief_reason": "摘要聚焦于基于机器学习基因签名对胶质母细胞瘤患者进行分层并重定位FDA批准药物，未披露具体药品或靶点信息。大学机构+preclinical重定位研究+GBM领域高未满足需求导致总体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3743", "id": "IVXM_5wBX1NQZOEH-LG5", "source_drug_name": "FDA-approved drugs", "title": "New precision treatments for glioblastoma", "abstract_text": "The main goal of this study is to develop precision treatments for glioblastoma (GBM). GBM is a deadly brain tumor with few treatment options, mainly due to high intra- and inter-tumoral heterogeneity manifested by diverse genetic alterations and cellular components within an individual tumor or among different patients. Previous efforts targeting molecular features have focused on three molecular subtypes — Classical (CL), Mesenchymal (ME), and Pro-Neural (PN) — but no effective treatments have been developed for each subtype. To overcome this challenge, we recently employed a machine learning algorithm to identify 31 essential survival genes, forming a new GBM progression gene signature (GBM-PGS) that divided patients into high- or low-risk (HR vs LR) of poor prognosis. Because these genes are functionally vital for cancer cell survival/growth, GBM-PGS predicts the progression of GBM patients more accurately than existing biomarkers such as EGFR, MGMT, and IDH1. Given the functional relevance of GBM-PGS to tumor cell survival and disease progression, we hypothesize that combining GBM-PGS with molecular subtyping will stratify GBM patients into distinct treatment groups, enabling the repurposing of FDA-approved drugs for precision medicine in this fatal disease. We stratified TCGA GBM patients and DepMap glioma cell lines into six subgroups: HR-CL, HR-ME, HR-PN, LR-CL, LR-ME, and LR-CL using GBM-PGS and molecular subtyping. The survival of TCGA subgroups was assessed using Kaplan-Meier analysis, and potential drug targets for the HR and LR groups were analyzed using Gene Ontology. Moreover, candidate precision treatments for each subgroup were identified from the DepMap PRISM Repurposing Drug Screen dataset and further verified in a range of GBM cell lines. The LR-PN displayed a significantly better prognosis than the other subgroups. Drugs targeted for HR GBMs were functionally different from those for LR GBMs. The six treatment subgroups exhibited diverse responses to chemical compounds, including FDA-approved drugs. Candidate drugs for each subgroup were validated in GBM cell lines. Our results have verified the crucial roles of GBM-PGS and molecular subtyping in patient stratification and in the development of subgroup-specific precision treatments. Overall, this study has the potential to transform the GBM therapeutic landscape.", "source_company": "Virginia Tech", "source_org_type": "大学", "row_number": 8, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "β1-integrin (ITGB1) blockade", "company": "Yale School of Medicine", "org_type": "大学", "target": "ITGB1", "modality": "inhibitor", "importance_level": "低", "total_score": 35.5, "institution_score": 25, "track_score": 45, "milestone_score": 35, "field_heat_score": 40, "bonus_score": 0, "brief_reason": "靶向肿瘤细胞间ITGB1介导的黏附作用以破坏肺癌克隆合作生长优势，机制新颖但仅为大学体外研究。机构为大学非商业研发、处于preclinical早期、无明确临床转化路径导致总体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1864", "id": "PVXM_5wBX1NQZOEH-LK6", "source_drug_name": "β1-integrin (ITGB1) blockade", "title": "Clonal diversity drives cooperative growth in lung cancer", "abstract_text": "Cell-cell communication within the tumor microenvironment is critical for cancer growth and therapy resistance. While many studies have focused on interactions between tumor cells and the surrounding microenvironment, this study investigates how interactions between distinct tumor cell states contribute to tumor growth. We constructed an in vitro system using the H1975-Clonebow lung cancer cell line, which allows for stochastic recombination of distinct fluorescent proteins to yield unique color signatures for lineage tracing. From the parental H1975-Clonebow line, we derived and expanded 218 single-cell clones and compared each clone’s growth rate to the heterogeneous parental population. The parental line grew faster than 86% of clones, suggesting a cooperative advantage of clonal diversity. Systematic “mixing” at fixed total cell numbers showed that mixed-clone populations consistently outperformed single clones, which we interpret as evidence for adaptive heterogeneity. Across 4-clone mixes, quantification during unmixing revealed that both fast- and slow-growing clones proliferated better in mixtures than in isolation, indicating non-random cooperation that promotes collective growth. To capture cooperation-associated programs, we performed bulk RNA-seq on clones fluorescently sorted after 4-clone mixing, with identically sorted single-clone cultures grown alone as controls. Transcriptomes clustered primarily by clone identity but converged on shared signaling modules in mixes, consistent with the observed growth boost. Mix-induced gene programs were more strongly enriched in malignant cells from patient-derived NSCLC tumors than programs from individually grown clones. Ligand-receptor (LR) analysis highlighted an integrin-centered adhesion program: multiple integrin LR pairs consistently ranked among the top tumor cell-cell interactions in vitro and in patient tumors, with β1-integrin (ITGB1) recurring as a hub. Consistent with this, β1-integrin blockade preferentially reduced the mix-specific growth advantage. Future experiments will involve longitudinal live-cell imaging to directly test whether the cooperative growth phenotype requires sustained inter-clone contact. Together, these data suggest that emergent cooperation between tumor cells promotes growth and may be targetable for therapeutics. Targeting β1-integrin-mediated adhesion at the tumor cell-cell interface represents a feasible strategy to disrupt cooperative growth in EGFR-mutant lung cancer.", "source_company": "Yale School of Medicine", "source_org_type": "大学", "row_number": 31, "target_meta": "ITGB1", "MOA_meta": "抑制剂"}, {"drug_name": "DNMT inhibitor", "company": "Van Andel Institute", "org_type": "研究机构", "target": "未披露", "modality": "inhibitor", "importance_level": "低", "total_score": 35.5, "institution_score": 25, "track_score": 45, "milestone_score": 35, "field_heat_score": 50, "bonus_score": 3, "brief_reason": "研究聚焦UHRF1-SUV39H1/H2通路作为DNMT抑制剂耐药机制的新靶点，可增强表观遗传治疗在实体瘤中的疗效，但药物本身为未特异性DNMT抑制剂。机构为研究机构且处于机制探索阶段，临床转化里程碑较弱，总价值有限。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/2193", "id": "B57M_5wBZznHJdnt_W7O", "source_drug_name": "DNMT inhibitor", "title": "Targeting UHRF1-SUV39H1/H2 crosstalk enhances DNMT1 inhibitor efficacy in colon cancer", "abstract_text": "DNA hypomethylating agent (DNMTi) efficacy is associated with the re-expression of epigenetically silenced tumor suppressor genes (TSGs) and transposable elements (TEs) in preclinical cancer models, yet their clinical efficacy in solid tumors is limited. An emerging mechanism of resistance to DNMTi involves compensation through repressive histone post-translational modifications (PTMs). Here, we define a targetable chromatin-based mechanism through UHRF1-SUV39H1/H2 crosstalk that reinforces transcriptional silencing in colon cancer cells exposed to DNMTi’s. Leveraging integrative epigenomic profiling and biochemical analyses, we discovered that transient DNA hypomethylation triggers UHRF1-dependent mono-ubiquitination of lysine 18 on histone H3 (H3K18ub), which in turn stimulates SUV39H1/H2 methyltransferases to deposit H3K9me3 at CpG island promoters of DNA methylation-silenced TSGs. This UHRF1-SUV39H1/H2 crosstalk establishes new heterochromatin domains that stabilize repression despite global DNA demethylation. Disrupting UHRF1 enzymatic function or an identified H3K18ub-recognition motif in SUV39H1 prevents H3K9me3 accumulation, increases TSG re-expression, and enhances DNMTi-induced antiproliferative effects in colon cancer cells. These findings reveal a compensatory heterochromatin signaling mechanism that limits DNMTi responses and identify the UHRF1-SUV39H1 pathway as a novel therapeutic target to improve epigenetic therapy efficacy in solid tumors.", "source_company": "Van Andel Institute", "source_org_type": "研究机构", "row_number": 94, "target_meta": "not available", "MOA_meta": "抑制剂"}, {"drug_name": "a non-replicative pseudotyped lentiviral platform", "company": "University of Miami Miller School of Medicine", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 35.5, "institution_score": 25, "track_score": 45, "milestone_score": 35, "field_heat_score": 40, "bonus_score": 0, "brief_reason": "该平台为工程化伪型慢病毒载体，针对上皮来源癌靶向基因递送，未明确具体治疗靶点或载荷基因。大学早期平台研究，modality非当前最热门赛道且无明确临床里程碑，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10425", "id": "EFXM_5wBX1NQZOEH-LG5", "source_drug_name": "a non-replicative pseudotyped lentiviral platform", "title": "Engineering a novel epithelial-tropic pseudovirus platform for targeted gene therapy to carcinomas", "abstract_text": "Carcinomas represent over 80% of all cancer diagnoses and remain difficult to treat due to genetic heterogeneity, acquired drug resistance, and limited therapeutic specificity. Oncolytic viral therapies (OVTs) have shown promise for many cancers; however, current platforms such as the modified herpes simplex virus rely on intratumoral delivery and remain highly immunogenic, restricting their use against deep-seated and metastatic epithelial malignancies. To address this, we developed a non-replicative pseudotyped lentiviral platform designed with epithelial tropism and stable genomic integration. Our engineered chimeric envelope surface receptor retains key native receptor interactions of the L1 capsid protein of the human papilloma virus, designed in-silico to exploit functional domains, while preserving vital molecular mechanisms. This glycoprotein, combined with lentiviral backbone elements, yields a morphologically intact virion, confirmed by negative-stain TEM, that avoids virus-like-particle formation prior to plasma membrane trafficking. Transduction assays demonstrated selective infection and sustained transgene expression in epithelial cell lines as opposed to non-epithelial controls. To enhance selectivity, cancer-specific promoters would further confine payload expression to malignant epithelial cells. The pseudovirus can deliver a larger payload (8-10 kb) greater than that of Adeno-Associated Virus (≤ 4.7 kb) supporting complex therapeutic cassettes, including suicide genes and barrier-repair payloads. Our ongoing in-vitro and in-vivo studies are evaluating therapeutic delivery and efficacy in specific carcinoma models.", "source_company": "University of Miami Miller School of Medicine", "source_org_type": "大学", "row_number": 321, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "chromomycin A2", "company": "University of São Paulo", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 35.5, "institution_score": 25, "track_score": 35, "milestone_score": 45, "field_heat_score": 40, "bonus_score": 0, "brief_reason": "chromomycin A2为GC-rich DNA结合剂，通过干扰染色质结构和抑制RNA聚合酶发挥多靶点抗白血病作用，但靶点机制非新型。大学机构preclinical体外和ex vivo数据较扎实但无明确靶向创新，整体开发热度和机构权重较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/2854", "id": "HFXM_5wBX1NQZOEH-LG5", "source_drug_name": "chromomycin A2", "title": "Chromomycin A2 disrupts leukemia cell viability via integrated autophagic and apoptotic programs", "abstract_text": "Acute leukemias urgently require new therapeutic approaches due to high relapse rates and frequent resistance to standard treatments. Advances in molecular profiling have enabled more selective and less toxic strategies, especially for patients with poor prognosis. Chromomycins have emerged as potential agents because they bind GC-rich DNA regions, alter chromatin architecture, inhibit RNA polymerase, and suppress transcriptional programs essential for leukemic cell survival. Among them, chromomycin A2 remains largely unexplored in hematologic cancers despite reported activity in some solid tumors. We investigated chromomycin A2 in a broad panel of leukemia models. Twenty-two human blood cancer cell lines were analyzed (14 myeloid, 17 lymphoid), including resistant variants to venetoclax (n=2), quizartinib (n=1), and ATRA (n=1). Viability (MTT), apoptosis (annexin V/PI), and autonomous clonal growth in cytokine-free methylcellulose were evaluated. Ex vivo assays used primary AML (n=3) and ALL (n=3) samples. Molecular analyses included PCR arrays covering genes related to autophagy, apoptosis, DNA damage, and cell-cycle control, together with Western blotting. Statistical significance was defined as p<0.05. Chromomycin A2 reduced viability in all models in a dose-dependent manner (IC50: 0.40 - 4.42 nM). Resistant derivatives showed slightly higher IC50 values but remained sensitive. The compound induced time- and dose-dependent apoptosis and fully suppressed autonomous clonal growth at ≥5 nM. Early responses involved autophagy markers (LC3B-II accumulation, SQSTM1/p62 reduction), compatible with decreased transcriptional output and weakened survival signaling. With longer exposure, apoptotic markers (cleaved PARP1) and DNA damage (γH2AX) predominated. Gene expression data indicated a temporal sequence: activation of autophagy and cell-cycle arrest at 6 h, followed by apoptosis-related genes at 12 h. Enrichment analyses highlighted macroautophagy, mitochondrial apoptosis, and G1 DNA damage checkpoint pathways. In ex vivo assays, IC50 values ranged from 1.6 to 31.8 nM, with 81-92% efficacy in primary AML and ALL cells. Chromomycin A2 displayed strong antileukemic activity across in vitro and ex vivo models, including resistant subtypes. Its sequential induction of autophagy, apoptosis, and DNA damage suggests a multitarget mechanism. The inhibition of clonal growth indicates potential activity against leukemic stem/progenitor cells. These results support further preclinical development. Supported by FAPESP, CAPES, and CNPq.", "source_company": "University of São Paulo", "source_org_type": "大学", "row_number": 329, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "NCI-H929 lipid-extracted-modified nanoliposomes", "company": "Massachusetts College of Pharmacy & Health Sciences", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 35.5, "institution_score": 25, "track_score": 45, "milestone_score": 35, "field_heat_score": 40, "bonus_score": 0, "brief_reason": "该产品为基于NCI-H929细胞脂质提取物修饰的脂质纳米粒，旨在提高多发性骨髓瘤细胞靶向递送，未明确药物靶点和负载内容。大学早期体外研究、preclinical初步阶段且无明确创新机制，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5565", "id": "elXM_5wBX1NQZOEH-LG5", "source_drug_name": "NCI-H929 lipid-extracted-modified nanoliposomes", "title": "Enhancing targeted delivery in multiple myeloma via novel NCI-H929 lipid-extracted-modified nanoliposomes", "abstract_text": "Background: Multiple myeloma (MM) is an incurable hematological malignancy characterized by the aberrant proliferation of plasma cells in the bone marrow. Current first line goals of therapy for newly diagnosed symptomatic MM aim to achieve minimal residual disease prior to transplant, a key predictor of overall survival. However, toxicities remain a rate limiting step during induction therapy. Cell membrane lipid-extracted nanoliposomes (CLENs) are a novel drug delivery system that can be optimized to preferentially target MM cells. Prior research involving the use of the multiple myeloma cell line, RPMI-8226, supports the use of lipid extracts (LE) to enhance targeting. This study aims to evaluate whether the inclusion of LE derived from an additional MM cell line, NCI-H929, will also enhance targeting, while decreasing nanoliposome uptake by model off-target and non-target cells.\nMethods: The MM (target) cell line explored in this study was NCI-H929. K562-GFP was used as the non-target cell line, and normal healthy peripheral blood mononuclear cells (PBMCs) served as the off-target cell control. Cells were seeded at a concentration of 20,000 cells/mL in vented centrifuge tubes and exposed for 1 hour to varying compositions of nanoliposome preparations including: DOPC, NCI-H929 lipid extract (LE), cholesterol (Chol), and DPPE-rhodamine for fluorescence studies. Nanoliposomes were prepared using a modified thin film method. Relative fluorescence intensity was determined using a fluorescence microplate reader.\nResults: Mean liposome diameters (± deviation) for DOPC formulations containing NCI-H929 LE were: DOPC (100%)- 188.6 ± 2 nm, DOPC/LE- 95/5 212.3 ± 2 nm, 90/10- 230.4 ± 2 nm, 85/15- 200 ± 4 nm, and 80/20- 142 + 1 nm. For formulations including cholesterol, diameters were: DOPC/Chol 90/10- 235 ± 2 nm and DOPC/Chol/LE 80/10/10- 227.4 ± 2 nm. Following 1 hour exposure of the target cell line to different concentrations of DOPC/LE, a statistically significant increase in uptake was observed in DOPC/LE preparations compared to DOPC alone: 95/5 and 90/10 (p < 0.0001), 85/15 (p < 0.001), and 80/20 (p < 0.05), with the highest uptake observed for 90/10. The addition of cholesterol did not further enhance uptake, and no significant uptake was observed in non-target or off-target cells compared to controls.\nConclusions: Our preliminary findings support that cellular uptake in MM cells may be increased via NCI-H929-LE modified nanoliposomes, with diminished uptake by non-target and off-target cell populations. Confirmation studies are currently underway, including cytotoxicity studies comparing conventional chemotherapy against NCI-H929 LE-modified nanoliposomal formulations.", "source_company": "Massachusetts College of Pharmacy & Health Sciences", "source_org_type": "大学", "row_number": 391, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "GABAA receptor inhibitor", "company": "Saint Joseph's University", "org_type": "大学", "target": "GABAA receptor β3 subunit", "modality": "inhibitor", "importance_level": "低", "total_score": 35.5, "institution_score": 25, "track_score": 45, "milestone_score": 35, "field_heat_score": 40, "bonus_score": 0, "brief_reason": "GABAA受体β3亚单位在TNBC中促进侵袭和EMT，通过Src-FAK信号通路发挥作用，但药物仅为GABAA receptor inhibitor，未披露具体分子。大学机构、非热门靶点赛道、纯机制研究处于preclinical早期，导致整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6066", "id": "Np7ECZ0BZznHJdntvNYd", "source_drug_name": "GABAA receptor inhibitor", "title": "Mechanistic studies on the role of GABA type A (GABAA ) ion channel receptor in tumor invasion and metastasis in triple negative breast cancer", "abstract_text": "Triple-negative breast cancer (TNBC) represents 15-20 percent of breast cancer cases and is associated with aggressive progression, metastasis, and limited treatment options. TNBC treatment relies on surgery, radiation, and chemotherapy, but these approaches are non-selective and highly toxic, emphasizing the need for novel molecular targets. Traditionally known for mediating inhibitory neurotransmission through chloride ion conductance, recent evidence implicates γ-aminobutyric acid type A ion channel-coupled receptors (GABAA R) in cancer cell proliferation, migration, and metastasis. Our previous studies demonstrated that β3 and α1 GABAA R subunits are overexpressed in TNBC cells, promoting chloride influx and cell survival. We also showed that pharmacological inhibition or shRNA-mediated GABAA R β3 subunit knockdown reduces proliferation and induces cell cycle arrest of TNBC cell lines. Epithelial-mesenchymal transition (EMT) drives cancer metastasis by enabling cells to lose adhesion, reorganize the cytoskeleton, degrade the extracellular matrix, and gain migratory properties. The steroid receptor coactivator and focal adhesion kinase (Src-FAK) axis plays a central role in these processes by regulating cell remodeling, promoting cell proliferation, and migration. Src-FAK activation also stimulates the PI3K/AKT pathway, enhancing cell survival and resistance to apoptosis. In addition, FAK activates Rho-GTPases, which regulate actin cytoskeleton reorganization and cell motility. In this study, we investigated whether GABAA R β3 subunit knockdown and pharmacological inhibition alter the invasive potential and EMT in TNBC. Our results showed that inhibiting GABAA R genetically and pharmacologically significantly reduced the invasive potential and reversed the EMT, as evidenced by decreased expression of mesenchymal markers (vimentin and N-cadherin) and increased expression of the epithelial marker E-cadherin as determined by Western blot analysis. Furthermore, β3 subunit knockdown decreased the expression of total Src and reduced the phosphorylation of both Src and FAK. Morphological assessment further demonstrated that β3 subunit knockdown reduced cell size, disrupted actin stress fibers, and altered actin distribution, consistent with impaired migratory capacity. To further define the molecular mechanisms downstream of GABAA R signaling, we will perform RNA sequencing on control and β3 knockdown TNBC cells to identify transcriptional pathways involved in invasion and metastasis. Collectively, these findings reveal that GABAA R β3 promotes TNBC cell proliferation, EMT, and invasion through Src-FAK signaling, highlighting GABAergic signaling as a promising therapeutic target in metastatic breast cancer.", "source_company": "Saint Joseph's University", "source_org_type": "大学", "row_number": 409, "target_meta": "GABRB3", "MOA_meta": "抑制剂"}, {"drug_name": "NSL-AJ-01", "company": "Florida A&M University", "org_type": "大学", "target": "PMPMEase", "modality": "inhibitor", "importance_level": "低", "total_score": 35.5, "institution_score": 25, "track_score": 45, "milestone_score": 35, "field_heat_score": 40, "bonus_score": 0, "brief_reason": "NSL-AJ-01为聚异戊二烯基膦酰酯类不可逆机制抑制剂，靶向PMPMEase干扰小GTP酶循环以诱导TNBC细胞氧化应激和死亡。机构为大学、处于早期体外研究阶段且靶点新颖性有限导致整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6552", "id": "plXM_5wBX1NQZOEH-LG6", "source_drug_name": "NSL-AJ-01", "title": "Synthesis, characterization, and biological evaluation of polyisoprenylated phosphonyl ester inhibitors on triple-negative breast cancer", "abstract_text": "Triple-negative breast cancer (TNBC) is an aggressive subtype lacking molecular targets and resistant to conventional therapy. Small GTPases such as RAS, RHO, and RAC regulate proliferation and cytoskeletal organization through prenylation and subsequent methylation-demethylation cycles. The methylation of prenylated cysteine residues by prenylated protein methyltransferase (PPMTase) and demethylation by polyisoprenylated methylated protein methyl esterase (PMPMEase) maintains GTPase turnover, activation and membrane localization. Overexpression of PMPMEase in cancers accelerates this cycle, disrupting the balance between methylated and demethylated states and sustaining aberrant MAPK and PI3K/AKT signaling that drives malignant growth. To selectively disrupt this process, polyisoprenylated phosphonyl ester inhibitors (PPEIs) were designed as irreversible, mechanism-based inhibitors that exploits PMPMEase’s substrate recognition. Each PPEI incorporates a farnesyl tail that mimics the prenylated cysteine terminus of native substrates, promoting high-affinity binding and covalent modification of the catalytic serine. PPEIs were synthesized from farnesylated cysteine precursors and characterized by NMR and ion-trap mass spectrometry. Treatment of MDA-MB-231 and MDA-MB-468 cells with PPEIs produced dose-dependent reductions in viability and actin cytoskeletal integrity. NSL-AB-01 exhibited EC₅₀ values of 4.1 µM (MDA-MB-231) and 3.3 µM (MDA-MB-468), while NSL-AJ-01 showed higher potency (3.2 µM and 2.7 µM, respectively). Actin-staining analysis revealed ~90% reduction in mean cell area, indicating impaired Rho-family GTPase signaling. Western blotting showed decreased p-AKT (-25% in MDA-MB-231; -50% in MDA-MB-468) and increased p-ERK (≈2.8-fold in MDA-MB-231; +70% in MDA-MB-468). To determine whether PPEI-induced cytotoxicity was associated with oxidative stress, intracellular ROS generation was quantified using DCFDA fluorescence. NSL-AJ-01 and NSL-AB-01 induced strong, concentration-dependent ROS production in TNBC cells. NSL-AJ-01 increased ROS levels approximately 25-fold in MDA-MB-231 and 24-fold in MDA-MB-468 at 3 µM (p < 0.001). NSL-AB-01 induced even greater oxidative responses, causing an approximately 32-fold increase of ROS in MDA-MB-231 and 30-fold increase in MDA-MB-468 at 3 µM (p < 0.0001). Together, these findings demonstrate that PPEIs induce oxidative damage to breast cancer cells, suppress pro-survival AKT signaling, and activate ERK-mediated stress pathways, driving cytoskeletal disassembly and reduced TNBC cell viability.", "source_company": "Florida A&M University", "source_org_type": "大学", "row_number": 427, "target_meta": "PMPMEase", "MOA_meta": "抑制剂"}, {"drug_name": "partially hydrolyzed guar gum", "company": "The Hormel Institute, University of Minnesota", "org_type": "研究机构", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 35.5, "institution_score": 35, "track_score": 25, "milestone_score": 40, "field_heat_score": 45, "bonus_score": 0, "brief_reason": "partially hydrolyzed guar gum (PHGG) 为益生元纤维，主要通过增加粪便短链脂肪酸改善肠道菌群失调，无明确药物靶点。机构为大学附属研究机构、非热门modality、仅动物模型干预、临床转化距离较远，故综合重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1283", "id": "11XM_5wBX1NQZOEH-LG6", "source_drug_name": "partially hydrolyzed guar gum", "title": "Prebiotic fiber supplementation mitigates the effects of maternal obesity on offspring’s gut microbiome and mammary tumorigenesis", "abstract_text": "The prevalence of maternal obesity has gradually increased over successive decades, with over 50% of pre-pregnant women in the United States at present time classified as overweight or obese. Maternal obesity exerts deleterious effects on numerous pregnancy outcomes and imparts enduring negative health consequences on offspring, including elevating female offspring’s susceptibility to and mortality from breast cancer. Since the gut microbiome contributes to obesity and its adverse effects, and influences breast carcinogenesis, we investigated here whether gut dysbiosis, characterized by reduced fecal short-chain fatty acid (SCFA) levels, in mouse offspring born to diet-induced obese C57BL/6 dams (OB offspring) contributed to their higher E0771 mammary tumor burden, compared with control offspring. Fecal microbiota transplant (FMT) from OB offspring increased E0771 mammary tumor burden in control offspring host, suggesting a causality between gut dysbiosis and increased mammary tumorigenesis in OB offspring. Further, levels of SCFA receptor FFAR2 in CD4+ T cells, CD8+ T cells and Foxp3+ regulatory T cells in Peyer’s patches in gut and in CD8+ T cells in tumors were significantly lower in control offspring receiving FMT from OB offspring donor than from control offspring donor. To determine if increased mammary tumorigenesis in OB offspring can be reversed by increasing fecal SCFA production by dietary fiber, we employed the MMTV-PyMT mammary tumor model, in which mammary tumors develop “spontaneously” by 4 months of age. Our results indicated that MMTV-PyMT OB offspring exhibited significantly increased mammary tumor burden compared with controls. Supplementing offspring via drinking water with partially hydrolyzed guar gum (PHGG), a prebiotic fiber, exhibited significantly lower mammary tumorigenesis and higher fecal levels of SCFA propionic acid than OB offspring receiving maltodextrin (MDX) control. In contrast, control offspring receiving PHGG did not show changes in mammary tumorigenesis, although PHGG supplementation increased their fecal butyric acid levels. These results suggest that increased mammary tumorigenesis in OB offspring are linked to their gut dysbiosis. In addition, prebiotic\nfiber PHGG, consumed by adult OB offspring, reverses adverse effects of maternal obesity on both their gut microbiome and mammary tumorigenesis.", "source_company": "The Hormel Institute, University of Minnesota", "source_org_type": "研究机构", "row_number": 462, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "AT-1 (8-O-acetylharpagide)", "company": "National Yang Ming Chiao Tung University", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 35.5, "institution_score": 30, "track_score": 40, "milestone_score": 35, "field_heat_score": 45, "bonus_score": 0, "brief_reason": "AT-1为从台湾筋骨草中纯化的天然化合物，通过诱导G2/M期阻滞、DNA损伤和凋亡发挥抗下咽癌作用并选择性增敏放疗，但未明确特异性分子靶点。大学机构基础研究阶段，天然小分子非热门modality且无明确新机制，整体开发价值较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9320", "id": "MlXM_5wBX1NQZOEH-LK6", "source_drug_name": "AT-1 (8-O-acetylharpagide)", "title": "Investigation of 8-O-acetylharpagide induced G2/M arrest and radiosensitization effects on hypopharyngeal cancer", "abstract_text": "[Purpose] AT-1 (8-O-acetylharpagide) is a natural compound purified from the endemic Taiwanese plant Ajuga taiwanensis and has been reported to possess anti-aging, anti-inflammatory, and anti-cancer properties, such as skin, liver and breast, but its potential role in Hypopharyngeal squamous cell carcinoma (HPSCC) remains unclear. This study aimed to systematically characterize the cellular responses to AT-1 in human hypopharyngeal carcinoma cells (FaDu) versus normal human periodontal ligament fibroblasts (PDL) and to evaluate its selective cytotoxic and radiosensitizing potential.\n[Methods] Cell viability was assessed using the MTT assay. Flow cytometry was performed to analyze cell-cycle distribution and apoptosis. DNA damage was evaluated by immunofluorescence staining and comet assay. Western blotting was used to detect changes in cell cycle- and apoptosis-related proteins. Radiation sensitivity was examined following AT-1 pretreatment and subsequent X-ray exposure.\n[Results] AT-1 selectively reduced the viability of FaDu cells while exerting minimal cytotoxicity in PDL cells and induced pronounced G2/M phase arrest in FaDu, accompanied by abnormal upregulation of Cyclin B1 and modulation of cell cycle regulators. Apoptosis analysis revealed that AT-1 triggered cell death through downregulation of pro-survival proteins including AKT, p-AKT, and Bcl-2. Intracellular reactive oxygen species levels did not significantly increase, suggesting that oxidative stress was not directly responsible for AT-1-induced cytotoxicity. Immunofluorescence and comet assays confirmed the presence of DNA double-strand breaks in AT-1-treated FaDu cells, which may underlie the observed G2/M arrest and apoptosis. Furthermore, AT-1 pretreatment enhanced the radiosensitivity of FaDu cells, whereas PDL cells remained relatively resistant to AT-1 alone and to the combination treatment. AT-1 inhibits the growth of hypopharyngeal carcinoma cells by perturbing the cell cycle, inducing DNA damage, and promoting apoptosis, and it acts as a selective radiosensitizer in this model.\n[Conclusions] These data demonstrate that AT-1 (8-O-acetylharpagide) induces G2/M arrest and selectively radiosensitizes hypopharyngeal cancer cells while sparing normal cells. AT-1 may represent a promising low-toxicity radiosensitizer candidate for head and neck cancer, and further in vivo and mechanistic studies are warranted to define its impact on DNA damage response.", "source_company": "National Yang Ming Chiao Tung University", "source_org_type": "大学", "row_number": 517, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "Tanshinone analog", "company": "Taipei Tzu Chi Hospital, Buddhist Tzu Chi Medical Foundation", "org_type": "医院", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 35.5, "institution_score": 25, "track_score": 35, "milestone_score": 45, "field_heat_score": 40, "bonus_score": 0, "brief_reason": "Tanshinone analog 通过诱导ER stress并抑制MYC和E2F通路发挥前列腺癌抗肿瘤作用，但靶点未明确披露。机构为医院非主流药企、modality为天然产物类似物非热门赛道、仅停留在动物水平研究，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8799", "id": "OFXM_5wBX1NQZOEH-LK6", "source_drug_name": "Tanshinone analog", "title": "Tanshinone analog induces ER stress mediated growth suppression via inhibition of MYC and E2F pathways in prostate cancer cells", "abstract_text": "Prostate cancer (PCa) is the most common malignancy among men in developed countries, and its increasing incidence is closely associated with the rising prevalence of obesity and metabolic syndrome. Our previous studies demonstrated that the Tanshinone analog (TA) enhances ATF3 expression, inhibits adipogenesis and lipogenesis, and promotes adipocyte browning. Although both native Tanshinones and their analogs have been reported to influence PCa cell growth, the underlying mechanisms remain incompletely understood. This study aimed to investigate whether TA regulates the growth of PCa cells through modulation of the endoplasmic reticulum (ER) stress/unfolded protein response (UPR) and E2F family-related pathways. Using androgen-dependent LNCaP cells and androgen-independent DU145 and PC3 cells as PCa models, we examined the effects of TA on cell growth and associated signaling pathways. TA treatment significantly reduced cell numbers in all three PCa cell lines in a dose-dependent manner, as determined by hemocytometer counting. Colony formation assays confirmed a marked decrease in both colony number and diameter, indicating strong anti-tumor activity. Gene Set Enrichment Analysis (GSEA) of RNA sequencing data revealed that TA markedly suppressed MYC- and E2F target-associated pathways in LNCaP and DU145 cells. In contrast, differential gene expression (DEG) enrichment analysis showed upregulation of ER stress-related pathways, which was further validated by qPCR and western blot analyses of ER stress markers including PERK, ATF6, IRE1α, ATF4, and CHOP. Additionally, TA reduced androgen receptor protein levels and its nuclear translocation in LNCaP cells. In vivo, TA treatment (10 mg/kg, i.p., twice weekly for six weeks) significantly reduced tumor growth in DU145 xenograft-bearing immunodeficient mice compared with controls (2.30 ± 0.23 g vs. 3.53 ± 0.43 g; P < 0.05). TA treatment also decreased lung weight relative to the control group (0.21 ± 0.03 g vs. 0.36 ± 0.06 g; P < 0.05), indicating effective inhibition of lung metastasis. Histological analysis further confirmed that both primary prostate tumors and metastatic lung tumors were smaller in the TA-treated group than in controls. Moreover, there was no biochemical evidence of hepatotoxicity or nephrotoxicity, as hepatic (ALT, AST) and renal (BUN, creatinine) biomarkers remained unchanged after six weeks of TA treatment. In conclusion, TA exerts multiple anti-tumor effects in PCa by activating ER stress and suppressing MYC- and E2F-related signaling. These findings highlight TA as a promising therapeutic candidate for prostate cancer treatment.", "source_company": "Taipei Tzu Chi Hospital, Buddhist Tzu Chi Medical Foundation", "source_org_type": "医院", "row_number": 520, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "small molecule inhibitors against Lipocalin-2", "company": "University of Puerto Rico - Rio Piedras", "org_type": "大学", "target": "Lipocalin-2", "modality": "inhibitor", "importance_level": "低", "total_score": 35.5, "institution_score": 25, "track_score": 45, "milestone_score": 35, "field_heat_score": 40, "bonus_score": 0, "brief_reason": "靶向Lipocalin-2的小分子抑制剂，针对炎性乳腺癌这一罕见亚型，机制新颖但靶点临床验证程度低。大学早期筛选阶段、无明确优化或体内数据，综合热度和开发阶段均较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4058", "id": "ZFXM_5wBX1NQZOEH-LK6", "source_drug_name": "small molecule inhibitors against Lipocalin-2", "title": "Characterization of small molecule inhibitors against Lipocalin-2 in inflammatory breast cancer", "abstract_text": "Inflammatory breast cancer (IBC) is a rare and very aggressive form of breast cancer (BC) where cancer cells block the lymph vessels in the skin. It only makes up about 1% to 5% of all breast cancers but grows and spreads much faster than other common BC types. No targeted therapies are currently available against IBC. Lipocalin 2 (LCN2) is a secreted glycoprotein involved in transporting small lipophilic ligands, and its abnormal expression plays an important role in the progression and metastasis of IBC. We used a library of 370,000 small molecule inhibitors (SMI) and after bioinformatic and filtering analysis we selected 24 compounds that potentially bind to LCN2. Viability and colony formation assay were performed on the IBC cell line, SUM-149. The majority of the 24 SMIs did not exhibited noticeable reduction on cell viability. However, at 1.0 µM, 12 SMIs achieved >50% reduction in cell proliferation. These results highlight the therapeutic potential and selectivity of SMIs against LCN2. Targeting this protein with our SMIs could provide a novel therapeutic strategy that improves the outcomes of IBC patients. Further studies are needed to validate and optimize the most effective compounds for future clinical development.", "source_company": "University of Puerto Rico - Rio Piedras", "source_org_type": "大学", "row_number": 549, "target_meta": "NGAL", "MOA_meta": "抑制剂"}, {"drug_name": "P053", "company": "SUNY Upstate Medical University", "org_type": "大学", "target": "PP5", "modality": "inhibitor", "importance_level": "低", "total_score": 35.5, "institution_score": 25, "track_score": 45, "milestone_score": 35, "field_heat_score": 40, "bonus_score": 0, "brief_reason": "P053为新型小分子PP5抑制剂，可诱导belzutifan耐药ccRCC细胞凋亡。大学早期preclinical研究，缺乏临床进展，赛道非主流热门导致整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5051", "id": "zVXM_5wBX1NQZOEH-LK6", "source_drug_name": "P053", "title": "Overcoming drug resistance in ccRCC through inhibition of protein phosphatase 5 (PP5)", "abstract_text": "BACKGROUND: Belzutifan is an FDA approved small molecule inhibitor used for the treatment of patients with advanced clear cell renal cell carcinoma (ccRCC). Belzutifan inhibits HIF2α, a transcription factor that promotes tumor angiogenesis and metastasis. Although ccRCC patients can potentially develop resistance to belzutifan there are currently no strategies to counteract this drug resistance in patients. We have identified that serine/threonine protein phosphatase-5 (PP5) expression and activity is elevated in ccRCC, contributing to its pro-survival role. We have designed and developed small molecule inhibitors of PP5. The objective of this study was to examine whether PP5 inhibition can cause apoptosis in belzutifan-resistant ccRCC cells.\nMETHODS: Belzutifan-resistant ccRCC cells were developed by treating 786-O cells with 10μM belzutifan. Once 70% confluent, the cells were split and treated with 10μM belzutifan again. This process was repeated until the cells appeared healthy and grew at a similar rate to 786-O without belzutifan treatment. Belzutifan was removed from the cells for at least 24 hours before additional drug treatments and/or protein extraction. Compound P053 is a second-generation small molecule inhibitor of PP5. Belzutifan-resistant ccRCC cells were treated with either 1μM or 10μM of P053 for 24 hours and apoptotic markers were evaluated by immunoblotting to examine cleaved caspase-3 and cleaved-PARP.\nRESULTS: The second generation PP5 inhibitor P053 has the ability to bind to the catalytic domain and inhibit the phosphatase activity of PP5. Belzutifan-resistant ccRCC cells are able to maintain growth in the presence of 10μM belzutifan and do not display any hallmarks of activation of apoptosis. Treatment of belzutifan-resistant cells with either 1μM or 10μM of P053, however, induced apoptosis, as evidenced by elevated levels of cleaved caspase-3 and cleaved-PARP.\nCONCLUSIONS: PP5 inhibition with our novel small molecule inhibitor retains the ability to cause apoptosis in belzutifan-resistant cells. This suggests PP5 is a viable therapeutic target in advanced ccRCC even after belzutifan resistance.", "source_company": "SUNY Upstate Medical University", "source_org_type": "大学", "row_number": 619, "target_meta": "TFPI2", "MOA_meta": "抑制剂"}, {"drug_name": "dimethylmalonate", "company": "The Hormel Institute, University of Minnesota", "org_type": "研究机构", "target": "SDH", "modality": "inhibitor", "importance_level": "低", "total_score": 35.5, "institution_score": 25, "track_score": 45, "milestone_score": 35, "field_heat_score": 40, "bonus_score": 0, "brief_reason": "dimethylmalonate为SDH抑制剂，靶向SDH酶活性以抑制内分泌治疗耐药的ER+乳腺癌细胞增殖。机构为大学研究机构、非热门modality+靶点、仅体外药理学水平，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4861", "id": "I1XM_5wBX1NQZOEH-LO6", "source_drug_name": "dimethylmalonate", "title": "Targeting succinate dehydrogenase impairs the proliferation of ER+ breast cancer cells", "abstract_text": "Endocrine therapies (ET) for estrogen receptor positive (ER+) breast cancer directly block either estrogen biosynthesis (aromatase inhibitors) or estrogen receptor function (Fulvestrant or tamoxifen). However, due to intrinsic and acquired resistance, disease progression often resumes despite continued ET. Succinate dehydrogenase (SDH) enzyme catalyzes the reversible conversion of succinate to fumarate. It contains four different subunits and SDH assembly factor 2 (SDHAF2). In our study, we found elevated SDH enzymatic activity and protein expression of SDHB (catalytic subunit) in LCC9 (ET-resistant cells) comparison with LCC1 or MCF-7 (ET-sensitive cells). T47D-4HT (ET-resistant) also showed significantly higher protein levels of SDHB in comparison with their parental T47D-A18 cells (ET). Pharmacological inhibition of SDH activity using dimethylmalonate (DMM) reduced cell growth, colony and spheroid formation in both LCC9 and T47D-4HT. DMM treatment induced caspase-dependent apoptosis and reduced mitochondrial membrane potential in both LCC9 and T47D-4HT cells. Importantly, succinate accumulation was accompanied by HIF 1-α stabilization and SDH inhibition led to lower levels of HIF1-α, which indicates that SDH may function in the conversion of fumarate to succinate in LCC9 cells. Genetic ablation of SDHB confirmed the importance of SDH activity in growth, colony and spheroid formation of LCC9 and T47D-4HT cells. Taken together, SDH enzymatic activity is crucial for the proliferation and mitochondrial function of ET-resistant ER+ breast cancer cells. We propose that SDH is a potentially novel therapeutic target for ER+, endocrine therapy resistant breast cancer.", "source_company": "The Hormel Institute, University of Minnesota", "source_org_type": "研究机构", "row_number": 673, "target_meta": "SDH", "MOA_meta": "抑制剂"}, {"drug_name": "Rbin-2", "company": "Florida A&M University College of Pharmacy & Pharmaceutical Sciences", "org_type": "大学", "target": "MDN1", "modality": "inhibitor", "importance_level": "低", "total_score": 35.5, "institution_score": 25, "track_score": 45, "milestone_score": 35, "field_heat_score": 50, "bonus_score": 2, "brief_reason": "Rbin-2为MDN1抑制剂，靶向核糖体生物合成关键调控因子MDN1以破坏AI耐药ER+乳腺癌中的SUMOylation轴和CSC特性。机构为大学、处于早期机制研究阶段、靶点非热门赛道导致整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4874", "id": "f1XM_5wBX1NQZOEH-LS6", "source_drug_name": "Rbin-2", "title": "Midasin inhibition disrupts the sumoylation axis to impair mammosphere stability through alteration of transcriptional network", "abstract_text": "Endocrine resistance remains a major barrier to effective treatment of estrogen receptor–positive (ER+) breast cancer, necessitating identification of molecular drivers that sustain tumor growth, plasticity, and cancer stem cell (CSC) associated phenotypes. Midasin (MDN1), a key regulator of ribosome biogenesis, is elevated in endocrine-resistant tumors, yet its contribution to aromatase inhibitor (AI) resistance is not well defined. Here, we examined differential responses to MDN1 inhibition in AI-sensitive AC-1 and AI-resistant LTLT-Ca cells cultured in 2D and 3D. Basal characterization showed higher aromatase (1.2-fold) and ERα (1.6-fold) expression in AC-1 cells, while LTLT-Ca cells exhibited 7-fold and 3.85-fold increase in EGFR and HER2, respectively, with further EGFR and HER2 amplification (up to 4-fold) in 3D mammosphere. Although MDN1 levels were higher in AC-1 cells under 2D conditions, MDN1 was enriched in LTLT-Ca mammosphere, linking elevated ribosome biogenesis to the resistant, stem-like phenotype. Treatment with the MDN1 inhibitor, Rbin-2 (18 µM) significantly reduced MDN1 expression and disrupted spheroid architecture in both models. AC-1 spheroids displayed moderate size reduction (1010.5 µm² to 731.7 µm² by day 12), whereas larger LTLT-Ca spheroids (1204.5 µm²) became fragmented and irregular (1539.3 µm²), indicating structural collapse rather than shrinkage. Acridine Orange/Ethidium Bromide staining revealed a 65% decrease in the live-to-dead fluorescence ratio in AC-1 versus 14% in LTLT-Ca, consistent with extensive degeneration in sensitive cells and instability in resistant spheroids. Spheroid invasion assays showed modest reduction in matrix outgrowth in both AC-1 and LTLT-Ca after Rbin-2 exposure. LTLT-Ca mammospheres expressed elevated OCT4 and SOX2, which decreased by 49% and 45% respectively, following MDN1 inhibition, implicating MDN1 in sustaining CSC transcriptional networks. Analysis of SUMOylation dynamics revealed intrinsically higher SUMO2/3 in resistant cells, with a further increase upon Rbin-2 treatment, consistent with decreased midasin associated cell death. Conversely, the deSUMOylase SENP3, also elevated in resistant cells, was reduced by Rbin-2 in both lines. This increase in SUMO2/3 coupled with decreased SENP3 reflects MDN1-dependent disruption of homeostasis and aligns with reduced ALDH1A1 and loss of CSC properties. Collectively, these findings identify a SUMO2/3–SENP3–MDN1 regulatory axis that supports, stemness and invasiveness in AI-resistant breast cancer, and demonstrate that MDN1 inhibition disrupts this axis to impair mammosphere integrity, attenuate CSC programs, and suppress invasion. This work establishes MDN1 as a promising therapeutic vulnerability for overcoming AI resistance.", "source_company": "Florida A&M University College of Pharmacy & Pharmaceutical Sciences\nFlorida A&M University", "source_org_type": "大学", "row_number": 922, "target_meta": "MDN1", "MOA_meta": "抑制剂"}, {"drug_name": "Rheum webbianum ethanolic extract", "company": "Lovely Professional University", "org_type": "大学", "target": "Wnt/β-catenin 和 TGF-β 通路", "modality": "other", "importance_level": "低", "total_score": 35.5, "institution_score": 25, "track_score": 40, "milestone_score": 45, "field_heat_score": 35, "bonus_score": 0, "brief_reason": "该提取物为天然植物粗提物，主要通过抑制Wnt/β-catenin和TGF-β信号通路显示体外和体内结直肠癌预防作用。机构为普通大学、处于早期非临床研究阶段且非热门靶点/模态，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6764", "id": "iJ7M_5wBZznHJdnt_W3O", "source_drug_name": "Rheum webbianum ethanolic extract", "title": "Chemopreventive effects of Rheum webbianum against colorectal cancer via modulation of Wnt/β-catenin and TGF-β signaling: Insights from in-vitro and in-vivo studies", "abstract_text": "Background: Colorectal cancer (CRC) is one of the most prevalent malignancies worldwide, largely influenced by lifestyle and environmental factors. The search for safe, natural chemopreventive agents remains a key research priority. Rheum webbianum Royle (RW), a Himalayan medicinal plant with notable ethnopharmacological significance, has shown promising anticarcinogenic activity in prior studies. Building on our earlier findings demonstrating its protective effects against DMH-induced colon carcinogenesis, the present study further explores the anticancer potential of RW ethanolic extract, focusing on its influence on molecular pathways and rectal tissue morphology.\nMethods: The ethanolic extract of RW was assessed using both in-vitro and in-vivo approaches. In HT-29 colorectal adenocarcinoma cells, cytotoxicity and wound-healing assays were used to examine antiproliferative and antimigratory effects. Western blotting analyzed alterations in β-catenin and TGF-β1 expression. In-vivo evaluation was performed using a 1,2-dimethylhydrazine (DMH)-induced CRC rat model to investigate molecular modulation and histopathological alterations in rectal tissues.\nResults: In-vitro, RW extract markedly reduced HT-29 cell viability in a dose- and time-dependent manner, reaching approximately 80% inhibition at 200 µg/mL, and significantly impaired cancer cell migration. In-vivo, RW treatment downregulated β-catenin and TGF-β1 expression, indicating inhibition of oncogenic and pro-metastatic signaling.Histopathology: Microscopic examination revealed marked restoration of rectal tissue architecture in RW-treated groups compared to DMH-only rats. RW-treated animals showed reduced epithelial disruption, congestion, inflammatory infiltration, crypt abscesses, and dysplasia, while DMH-only groups exhibited severe mucosal damage, irregular glandular organization, and extensive inflammatory lesions with crypt abscesses and dysplasia. These findings suggest the protective efficacy of RW extracts in preventing DMH-induced colorectal tissue degeneration.\nConclusion: The ethanolic extract of Rheum webbianum demonstrates strong chemopreventive potential against colorectal carcinogenesis by suppressing tumor cell proliferation, migration, and aberrant activation of Wnt/β-catenin and TGF-β signaling pathways, along with restoring rectal tissue integrity. These outcomes support RW as a promising natural candidate for colorectal cancer prevention and integrative therapeutic development.", "source_company": "Lovely Professional University", "source_org_type": "大学", "row_number": 1041, "target_meta": "Wnt pathway,TGF-β", "MOA_meta": "其他"}, {"drug_name": "TNF-α and IFN-γ primed human Wharton's jelly mesenchymal stem cells", "company": "Sir Ganga Ram Hospital", "org_type": "医院", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 35.5, "institution_score": 25, "track_score": 45, "milestone_score": 35, "field_heat_score": 40, "bonus_score": 0, "brief_reason": "该产品为经TNF-α和IFN-γ预处理的脐带华通胶间充质干细胞，旨在通过免疫调节改善胰腺癌微环境，但靶点未明确披露，属于细胞治疗范畴。机构为医院而非药企，研究仍处于机制探索的preclinical早期阶段，无明确临床里程碑，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9389", "id": "Mp7M_5wBZznHJdnt_W7O", "source_drug_name": "TNF-α and IFN-γ primed human Wharton's jelly mesenchymal stem cells", "title": "Pro-inflammatory cytokine primed Wharton’s jelly mesenchymal stem cells: A potent immunomodulatory strategy to combat pancreatic cancer", "abstract_text": "Background & Aim: Mesenchymal stem cells (MSCs) from umbilical cord (UC) have the potential therapeutic applications in context of injured, immune related & inflammatory diseases due to high proliferation rate, multilineage differentiation potential and immune tolerance properties. While clinical trials have clearly demonstrated strong safety records, efficacy of MSCs is still modest and inconsistent. Hypothesizing that priming MSCs prior to administration can improve their therapeutic efficacy, present study investigates the modulation of MSC behaviour through cytokine priming and assesses their effectiveness in ameliorating tumor apoptosis. Proteomic analysis shows compositional changes post cytokine priming.\nMethod: Wharton’s jelly derived MSCs (hWJMSCs) were primed with tumor necrosis factor-alpha (TNF-α; 25ng/ml) and interferon-gamma (IFN-γ; 25ng/ml), incubated for 24 hrs at 37°C/5%CO2, their morphological alterations, multi-lineage differentiation potentials (osteocytes/chondrocytes/adipocytes), immunophenotypying (CD90+73+105+44+34-45-19- HLADR-), Adhesion molecules (ICAM, VCAM, NCAM) migration capabilities were examined.Label-free quantitative LCMS (nLC/MS/MS coupled to Orbitrap fusion Tribrid mass-spectrometer) analysis was performed on more than 2400 proteins identified. Further, immunogenic potentials are being tested using PBMNCs from healthy human donors.\nResult: hWJMSCs primed with TNF-α (hWJMSC-T)/IFN-γ (HWJMSC-I) showed >90% expression of CD90+73+105+44+. Microscopically morphological distinction stained with phyalloidin/DAPI observed showed hWJMSC-T as elongated and flattened cells and Complement & coagulation cascade and Pro-angiogenic proteome signature in abundance, suggesting their role in innate immunity homeostasis. On the other hand, IFN-γ induction showed immune-modulating protein signature of infection/inflammation especially, Guanylate-binding proteins. Differentially expressed protein signature points towards modulation of NOD-like receptor signaling and cell adhesion molecule pathways.\nConclusion: Data herein provides the evidences that stem cell properties of regenerative capability remains conserved and do not compromise under inflammatory conditions. Additionally, primed hWJMSCs can modulate or prevent infection most likely via cross-talk between cascades of defense systems. Thus, suggesting a potential role as alternate strategy to regulate inflammation and/or reshape inflammatory microenvironment.\nKeywords: Mesenchymal stem cells, pro-inflammatory cytokines, inflammation, immunomodulation", "source_company": "Sir Ganga Ram Hospital", "source_org_type": "医院", "row_number": 1159, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "calcium inhibitors", "company": "Fuzhou University Affiliated Provincial Hospital", "org_type": "医院", "target": "未披露", "modality": "inhibitor", "importance_level": "低", "total_score": 35.5, "institution_score": 25, "track_score": 45, "milestone_score": 35, "field_heat_score": 50, "bonus_score": 0, "brief_reason": "药品为非特异性钙信号抑制剂，靶点未明确披露，仅在体外/体内机制研究中显示可部分逆转DCLK1介导的胰腺癌进展和化疗耐药。机构为附属医院，开发阶段为preclinical机制探索，无明确药物候选物推进，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10718", "id": "u53ECZ0B4z9FlvORyiZD", "source_drug_name": "calcium inhibitors", "title": "Matrix stiffness induces Ca²⁺-DCLK1-PIP5K1A mechanotransduction as a biomechanical checkpoint in pancreatic cancer progression and chemotherapy resistance", "abstract_text": "Background: Alterations in extracellular matrix (ECM) architecture and stiffness are hallmarks of rapid pancreatic cancer progression. However, the mechanisms by which ECM biomechanical properties influence malignant biological behavior remain largely unknown. Calmodulin-dependent protein kinase DCLK1 has been implicated in cancer progression, but its role in integrating biomechanical signals in pancreatic cancer has not been elucidated.\nMethods: We investigated the relationship between ECM stiffness and DCLK1 activation in pancreatic cancer using in vitro biomechanical stress models and in vivo solid tumor experiments. DCLK1 expression and activity were manipulated via overexpression or knockdown, and calcium signaling was modulated using specific inhibitors. Single-cell RNA sequencing was performed to identify potential pathways by which calcium inhibition sensitizes tumors to chemotherapy. Multicolor immunofluorescence staining of clinical tumor samples was used to examine the correlation between the PIEZO1-DCLK1-PIP5K1A-AKT signaling axis and ECM stiffness in situ. Mechanistic studies included protein interaction assays and phosphorylation analyses to define the DCLK1-PIP5K1A-PI3K-AKT signaling cascade.\nResults: DCLK1 expression and activation were selectively induced under high biomechanical stress mediated by the PIEZO1/calcium/HPCAL1 axis. Overexpression of DCLK1 under low stiffness conditions accelerated tumor progression and chemoresistance, which could be partially reversed by calcium inhibitors. Conversely, under high stiffness conditions, DCLK1 knockdown inhibited tumor growth and increased chemosensitivity, but attenuated the sensitizing effect of combined calcium inhibitor treatment. Single-cell RNA sequencing identified calcium-related pathways contributing to chemotherapy sensitization. Mechanistically, DCLK1 interacted with PIP5K1A by inhibiting its threonine phosphorylation, promoting membrane localization of PIP5K1A and activating the downstream PI3K-AKT pathway. Multicolor immunofluorescence confirmed the correlation of PIEZO1-DCLK1-PIP5K1A-AKT activation with ECM stiffness in clinical samples.\nConclusions: DCLK1 functions as a biomechanical checkpoint in pancreatic cancer, integrating ECM-derived mechanical cues to exacerbate tumor progression and chemotherapy resistance. Targeting the calcium/DCLK1 signaling axis may enhance the efficacy of adjuvant therapy in pancreatic cancer patients", "source_company": "Fuzhou University Affiliated Provincial Hospital", "source_org_type": "医院", "row_number": 1206, "target_meta": "not available", "MOA_meta": "抑制剂"}, {"drug_name": "2-hydroxyflavanone", "company": "UT Health Houston", "org_type": "医院", "target": "RLIP", "modality": "other", "importance_level": "低", "total_score": 35.2, "institution_score": 25, "track_score": 45, "milestone_score": 35, "field_heat_score": 40, "bonus_score": 2, "brief_reason": "2-hydroxyflavanone为天然来源小分子，通过抑制RLIP（RALBP1）降低HR相关基因表达，从而增敏BRCA野生型乳腺癌对PARP抑制剂的敏感性。机构为医院/大学类型非商业化研发、仍处于细胞水平研究且无明确临床推进，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/2005", "id": "6lXM_5wBX1NQZOEH-LO6", "source_drug_name": "2-hydroxyflavanone", "title": "Potentiation ofPARP inhibitor activity inBRCA-wildtype breast cancer cell lines by 2-hydroxyflavanone", "abstract_text": "Background: 2-hydroxyflavanone (2HF) is citrus derived compound which has demonstrated in vitro anticancer activity against multiple malignancies. Its presence inhibits RLIP, a protein encoded by RALBP1 gene which functions as an ATP dependent efflux pump for glutathione-electrophile conjugates, oxidative and alkylating intermediates and, mediates epidermal growth factor receptor endocytosis. Thus RLIP promotes oncogenesis with growth modulation and ability to resist chemotherapy with glutathione mediated xenobiotic efflux. Reduced RLIP expression by 2HF reduces spontaneous carcinogenesis in p53 null mouse models, indicating its utility in tumors with DNA repair-deficiency. BRCA1, BRCA2, and PALB2 are the pivotal genes involved in homologous recombination (HR) mutation which can be targeted by poly(ADP-ribose) polymerase pathway (PARP) inhibitors. Through this study we assessed the effects of PARP inhibitor AZD2461 alone and in combination with 2HF on cell viability of MDA-MB-231 and MCF-7 breast cancer cell lines.\nMethods: Expression of mRNA of BRCA1, BRCA2 and PALB2 genes was assessed in MDA-MB-231 (triple negative) and MCF-7 (ER+) breast cancer cell lines after exposure to 2HF and LNA by using quantification cycle in Polymerase chain reaction. LDH release at 72 hours was measured and compared with controls in cells treated with 2HF or AZD2461 alone or in combination. Cytotoxicity was measured using absorbance of reduced WST-8 produced by the viable cells.\nResults: RLIP depletion by 2HF reduced the expression of mRNA of HR genes BRCA1, BRCA2, and PALB2 to 2% - 20% of the level of untreated controls. PARP inhibitor induced LDH release with incremental dose of 2HF at 10, 20 and 40 µM, with greatest cytotoxic effects at 40 µM 2HF (p < 0.001). Addition of 2HF to PARP inhibitor AZD2461 increased cell lysis in MCF-7 and MDA-MB-231 cells, however only diminished cell viability in MCF-7 but not in MDA-MB-231.\nDiscussion: PARP inhibitors are very effective in tumors with HRD mutation, however their utility is limited in subjects with mutations involving non HRD pathways. RALBP1 inhibition with 2HF decreases the expression of gene involved in HR pathway thus stimulating a transcriptomic environment that is similar to HRD mutated cells. 2HF could thus sensitize BRCA-wildtype ER+ and possibly triple negative breast cancers to PARP inhibitors. This potentially has clinical application among patients who may benefit from PARP inhibitors outside of current indications such as BRCA or HRD deficient mutations. Through this work, we look forward to inspire more work on clinical exploration of 2HF with PARP inhibitors.", "source_company": "UT Health Houston", "source_org_type": "医院", "row_number": 815, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "immune checkpoint blockade", "company": "The Chinese University of Hong Kong", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 35, "institution_score": 30, "track_score": 40, "milestone_score": 30, "field_heat_score": 50, "bonus_score": 0, "brief_reason": "药品实际为免疫检查点阻断疗法（非具体药物），无明确靶点或新modality披露，仅为背景治疗；机构为大学，赛道为已有成熟ICB，研究聚焦HDAC9机制而非药物开发，故整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10829", "id": "jFXM_5wBX1NQZOEH-LK6", "source_drug_name": "immune checkpoint blockade", "title": "Histone deacetylase 9 (HDAC9) mediates therapy resistance by regulating tumor-neutrophil interaction in advanced hepatocellular carcinoma", "abstract_text": "Tyrosine kinase inhibitors (TKIs) and immune checkpoint blockade (ICB) therapies are standard treatments for advanced hepatocellular carcinoma (HCC), but their efficacy is limited by therapy resistance. This study investigates the mechanisms underlying resistance, focusing on the role of tumor-immune interaction. Using single-cell RNA sequencing (scRNA-seq) in a TKI-treated immunocompetent mouse model, we identified an expansion of poorly differentiated tumor cells with significant upregulation of histone deacetylase 9 (HDAC9). Elevated HDAC9 enhanced cancer stemness and reduced the efficacy of TKI therapy. Beyond TKIs, HDAC9 also contributed to ICB resistance by suppressing CD8+ T cell infiltration and cytotoxicity, partly through interactions with immunosuppressive neutrophils exhibiting a neutrophil extracellular trap (NET) phenotype. Neutrophil depletion reversed ICB resistance, restoring CD8+ T cell infiltration and function. Mechanistically, HDAC9 deacetylates translation initiation factor 4 gamma 2 (eIF4G2), enhancing its interaction with YTHDF3 to promote m6A-dependent protein translation, including signaling molecules that mediate tumor-neutrophil crosstalk. Clinicopathological analysis confirmed that HDAC9 correlates with increased neutrophil infiltration and reduced cytotoxic immune activity in HCC patients. These findings identify HDAC9 as a key immunoregulator driving therapy resistance and suggest that targeting the HDAC9/eIF4G2/YTHDF3 axis may improve the efficacy of TKI and ICB therapies in advanced HCC.", "source_company": "The Chinese University of Hong Kong", "source_org_type": "大学", "row_number": 42, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "ALK inhibitors", "company": "Saitama Medical University International Medical Center", "org_type": "医院", "target": "ALK", "modality": "inhibitor", "importance_level": "低", "total_score": 35, "institution_score": 25, "track_score": 60, "milestone_score": 20, "field_heat_score": 40, "bonus_score": 0, "brief_reason": "该项研究针对已上市ALK抑制剂的off-target激酶与不良反应关联，使用新型磷酸化分析平台进行机制探索，而非新药开发。机构为医院，开发阶段为基础研究，无明显临床里程碑，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4402", "id": "iVXM_5wBX1NQZOEH-LG6", "source_drug_name": "ALK inhibitors", "title": "Association of off targets of ALK inhibitors with their adverse reactions revealed by a novel comprehensive phosphorylation profiling platform", "abstract_text": "Introduction: Five ALK inhibitors are currently approved for clinical use. Although all target ALK fusion proteins, their side-effect profiles differ markedly. These variations are suspected to result from off-target kinase interactions, but the molecular links remain unclear. We aimed to reveal this connection using a novel phosphorylation-based profiling system that comprehensively maps kinase-substrate relationships and pathway activations.\nMaterials and Methods: Using a recently developed cell-free phosphorylation array, we measured the overall phosphorylation activity within cells. This system does not focus on specific phosphorylation sites; instead, it identifies substrates that become phosphorylated under each experimental condition from a pool of 1,492 proteins (816 substrates for 190 kinases and 845 proteins constituting 273 pathways).Cell lysates treated with ALK inhibitors were applied to the array, enabling phosphorylation reactions that mimic intracellular kinase activity. Computational analyses extracted three layers of information, condition-specifically phosphorylated substrates, activated pathways and kinases, allowing simultaneous assessment of both on-target and off-target effects.\nResults: Phosphorylation profiles induced by five ALK inhibitors were measured in EML4-ALK mutant cell line (NCI-H2228 [H2228]), and analyzed across substrates, kinases, and pathways. Each drug exhibited a distinct inhibition signature, indicating specific kinases and pathways selectively affected beyond ALK. Several off-target kinases and pathways associated with known clinical adverse reactions, providing mechanistic insight into drug-specific toxicities.\nConclusion: This comprehensive phosphorylation profiling platform enabled simultaneous evaluation of on-target and off-target effects of kinase inhibitors. By linking molecular signaling changes to clinical side effects, the system provides a powerful approach for understanding complex kinase networks and guiding the development of safer next-generation inhibitors.", "source_company": "Saitama Medical University International Medical Center", "source_org_type": "医院", "row_number": 402, "target_meta": "ALK", "MOA_meta": "抑制剂"}, {"drug_name": "cGMP-phosphodiesterase inhibitor", "company": "University of Arizona Cancer Center", "org_type": "研究机构", "target": "未披露", "modality": "inhibitor", "importance_level": "低", "total_score": 35, "institution_score": 30, "track_score": 50, "milestone_score": 20, "field_heat_score": 40, "bonus_score": 0, "brief_reason": "药物为cGMP-磷酸二酯酶抑制剂，靶点未明确披露，拟用于调控胃癌及胃食管结合部腺癌肿瘤微环境，但摘要被embargo无具体机制或数据披露。机构为大学癌症中心非头部药企，处于概念或早期研究阶段无清晰里程碑，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/12165", "id": "91XM_5wBX1NQZOEH-LK6", "source_drug_name": "cGMP-phosphodiesterase inhibitor", "title": "Modifying the tumor microenvironment in gastric and gastroesophageal junction adenocarcinoma using a cGMP-phosphodiesterase inhibitor", "abstract_text": "Abstract is embargoed at this time.", "source_company": "University of Arizona Cancer Center", "source_org_type": "研究机构", "row_number": 648, "target_meta": "not available", "MOA_meta": "抑制剂"}, {"drug_name": "iPB", "company": "University of Naples Federico II", "org_type": "大学", "target": "未披露", "modality": "postbiotic", "importance_level": "低", "total_score": 34.5, "institution_score": 25, "track_score": 40, "milestone_score": 35, "field_heat_score": 45, "bonus_score": 0, "brief_reason": "iPB为基于L.paracasei NPB01和L.rhamnosus GG序贯发酵的后生元制剂，靶点机制未明确披露，仅体外显示对乳腺癌细胞株的抗肿瘤活性。大学机构+早期体外研究+后生元赛道非主流热门导致总体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5550", "id": "jvTW_5wBLOutsWDvgbHs", "source_drug_name": "iPB", "title": "Postbiotic based on sequential fermentation of L.paracasei NPB01 and L.rhamnosus GG exerts antitumor activities against breast cancer", "abstract_text": "Backgroud. Breast cancer (BC) is the most common and deadly cancer in women worldwide. Emerging evidence highlights the role of gut microbiota in modulating breast cancer risk, treatment response, and recurrence through various mechanisms, including the production of biologically active compounds and metabolites. These non-viable microbial products and metabolic byproducts from probiotic fermentation, known as postbiotics, exert beneficial effects on the host without the need for live microorganisms. Postbiotics derived from Lacticaseibacillus species represent a novel class of therapeutics with potential anti-cancer properties. In this study, we investigated the therapeutic effects of an innovative postbiotic product (iPB), developed through sequential fermentation of L.paracasei NPB01 and L.rhamnosus GG, in BC experimental models.\nMethods. The following cell lines were used to represent main BC subtypes: MCF7 cells (ER+/HER2), MDA-MB-231 (triple negative breast cancer), SKBR3 (HER2+). MCF-10A (normal breast epithelial cells), Caco-2 (enterocytes), and peripheral mononuclear blood cells (PBMC) were used as control. Cell viability was assessed by colony formation assay. Apoptosis was evaluated using Annexin V/7-AAD staining, HLA class I surface expression by flow cytometry, and cancer cells migration by wound healing assay.\nResults. iPB exposure resulted in >50% colony formation reduction in MCF7, >30% in MDA-MB-231 and >40% in SKBR3 cells starting from 0.5 mg/ml for 72 h (p<0.01). iPB increased early and late apoptotic cell rate in all BC cell lines starting from 0.5 mg/ml for 72 h. On the contrary, iPB exposure up to 5 mg/ml for 120 h did not affect cell viability in control cells (MCF-10A, Caco-2, PBMC). 1.20 to 1.30 fold increase in HLA class I expression was observed in all BC cell lines after the exposure with iPB starting from the dose of 0.5 mg/ml for 72 h. A less intense HLA class I expression increase was observed in control cells after the iPB exposure. Cell migration process and inflammatory cytokines response were inhibited by the iPB exposure in all BC cell models.\nConclusions. iPB reduces cell viability and cell migration in all main BC phenotypes. These effects parallel with HLA class I surface expression increase in all BC cell phenotypes, potentially enhancing immunogenicity. These findings suggest that iPB may represent a promising novel agent in BC treatment and prevention.", "source_company": "University of Naples Federico II", "source_org_type": "大学", "row_number": 380, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "ζ-Stat", "company": "University of South Florida", "org_type": "大学", "target": "PKC-ζ", "modality": "inhibitor", "importance_level": "低", "total_score": 34.5, "institution_score": 25, "track_score": 40, "milestone_score": 35, "field_heat_score": 50, "bonus_score": 0, "brief_reason": "ζ-Stat为选择性PKC-ζ小分子抑制剂，靶向非典型PKC isoform抑制前列腺癌骨转移相关信号，但仅大学机构体外研究，处于早期preclinical阶段，无明显临床进展或突破机制。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4424", "id": "flXM_5wBX1NQZOEH-LG5", "source_drug_name": "ζ-Stat", "title": "Targeted inhibition of atypical PKC isoforms PKC-ι and PKC-ζ by ICA-1S and ζ-Stat suppresses oncogenic signaling and cytokine-mediated bone metastasis in prostate cancer", "abstract_text": "Bone metastatic prostate cancer (BMPC) remains the leading cause of mortality among prostate cancer patients due to its resistance to current therapeutics and its reliance on the osteogenic microenvironment. The atypical protein kinase C (aPKC) isoforms PKC-ι and PKC-ζ have emerged as pivotal regulators of prostate cancer progression, metastasis, and inflammatory signaling. In this study, we investigated the molecular effects of two selective small-molecule inhibitors, ICA-1S (targeting PKC-ι) and ζ-Stat (targeting PKC-ζ), in DU-145 and PC-3 prostate cancer cells, as well as their interactions with the human osteoblast line hFOB 1.19. Our results demonstrated that both inhibitors effectively suppressed phosphorylation and activity of PKC-ι/ζ and downstream effectors, including Stat3, NFκB, and JNK/c-Jun, leading to marked reductions in cell migration and survival. Cytokine array analysis revealed that ICA-1S and ζ-Stat treatment significantly downregulated pro-metastatic and pro-inflammatory cytokines, including IL-6, IL-8, and CXCL-1, while upregulating IL-18 and ICAM-1, indicating a shift toward apoptotic and pyroptotic signaling. Immunofluorescence confirmed a decreased nuclear localization of Stat3. At the same time, co-immunoprecipitation assays demonstrated a reduced interaction between 14-3-3 and PKC-ι/ζ, supporting the disruption of key scaffold assemblies required for metastatic signaling. Collectively, our findings suggest that dual aPKC inhibition attenuates critical oncogenic cascades and reprograms the osteogenic niche to suppress prostate cancer survival and colonization in bone. These results identify ICA-1S and ζ-Stat as promising lead compounds for precision targeting of aPKC-driven prostate cancer metastasis.", "source_company": "University of South Florida", "source_org_type": "大学", "row_number": 393, "target_meta": "PKCζ", "MOA_meta": "抑制剂"}, {"drug_name": "C1", "company": "University of Virginia School of Medicine", "org_type": "大学", "target": "AVIL", "modality": "inhibitor", "importance_level": "低", "total_score": 34.5, "institution_score": 25, "track_score": 40, "milestone_score": 35, "field_heat_score": 45, "bonus_score": 0, "brief_reason": "C1为针对AVIL（胶质母细胞瘤中异常表达的肌动蛋白结合蛋白）的first-in-class小分子抑制剂，机制涉及调控糖酵解向氧化磷酸化代谢转变。大学机构+早期preclinical研究+非热门靶点导致整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6181", "id": "kVXM_5wBX1NQZOEH-LG6", "source_drug_name": "C1", "title": "An investigation into the role of AVIL, an actin-binding protein, in glioblastoma metabolism", "abstract_text": "Glioblastoma (GBM) is one of the deadliest cancers characterized, is highly aggressive, invasive, and incurable, with an average survival of 15 months. The Li Lab identified AVIL as a novel proto-oncogene, which is aberrantly expressed in the tissue of cancers like glioblastoma.  AVIL is a calcium dependent actin binding protein, implicated in cytoskeletal dynamics. Under physiological conditions, the expression of AVIL is limited to a handful of cell types: tuft cells, kidney podocytes, and sensory neurons, suggesting a tightly regulated role. In addition, our lab generated an AVIL KO mouse model that has no side effects and are fertile with viable offspring. Previous work has led to the development of a first-in-class small molecule inhibitor against AVIL (C1). While the upregulation of AVIL is observed in GBM, the molecular mechanisms involved are still unknown. This project aims to define the interactions and pathways involving AVIL with the goal of determining a molecular mechanism regarding alterations in metabolic phenotype. To elucidate the molecular mechanism of AVIL, we used a comprehensive bioinformatic analysis to pinpoint pathways and downstream targets. We conducted an unbiased screen of the protein using mass spectrometry on glioblastoma (U87) cells treated with C1 over a period of 72 hours. We also utilized RNA sequencing of GBM cells treated with C1 and astrocytes transduced with AVIL. Furthermore, we utilized Seahorse Mitochondrial Stress Tests as a screen for metabolism and mitochondrial function to validate our bioinformatic observations. One candidate mechanism we observed in the MS data suggested that treatment with the inhibitor induced a proteomic change from a glycolytic to an oxidative-phosphorylation profile, indicating a potential metabolic modulatory role of AVIL. This is particularly interesting because actin-glycolytic enzyme interactions are linked to the cytoskeletal regulation of metabolism. In addition, RNA sequencing data presented glycolysis as a top gene set that is differentially expressed after treatment with C1. After exogenous expression of AVIL in human astrocytes, there is an increase in basal metabolic rate and maximal respiration. Defining the metabolic interactions of AVIL will help determine the signaling pathways that are perturbed by AVIL expression and reveal downstream effectors.  I hypothesize that AVIL expression regulates glycolysis via interactions with glycolytic enzymes offering a potential therapeutic strategy for GBM.", "source_company": "University of Virginia School of Medicine", "source_org_type": "大学", "row_number": 406, "target_meta": "AVIL", "MOA_meta": "抑制剂"}, {"drug_name": "oleuropein", "company": "Jeju National University", "org_type": "大学", "target": "PKA", "modality": "other", "importance_level": "低", "total_score": 34.5, "institution_score": 25, "track_score": 40, "milestone_score": 35, "field_heat_score": 45, "bonus_score": 0, "brief_reason": "Oleuropein直接抑制PKA催化活性并通过ERK促进MITF降解，从而下调黑色素瘤中MITF水平。机构为大学、非热门modality、仅机制研究无开发进展导致整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6542", "id": "CVXM_5wBX1NQZOEH-LK6", "source_drug_name": "oleuropein", "title": "Oleuropein downregulates MITF via direct PKA inhibition and ERK-mediated turnover in melanoma", "abstract_text": "The Microphthalmia-associated Transcription Factor (MITF) acts as a molecular rheostat in melanoma, governing the switch between proliferative and invasive phenotypic states. Since constitutive activation of the PKA-CREB axis drives high MITF levels to sustain tumor proliferation, targeting this pathway offers a promising therapeutic strategy. Here, we elucidate the mechanism by which oleuropein modulates MITF stability and expression in melanoma and normal melanocyte models. In B16F10 melanoma cells characterized by aberrant PKA signaling, oleuropein directly inhibited PKA catalytic activity, leading to reduced CREB phosphorylation and subsequent transcriptional suppression of MITF. Furthermore, oleuropein triggered ERK1/2 activation, accelerating MITF protein turnover. Consequently, oleuropein dismantled the hyper-proliferative transcriptional program through dual upstream and downstream regulatory mechanisms. Crucially, oleuropein reduced basal MITF levels in normal human melanocytes and effectively blunted MITF spikes induced by α-MSH or forskolin. This suggests that oleuropein functions as a potent inhibitor of the PKA-CREB axis, preventing pathological signaling amplification under both basal and hyperactivated conditions. In conclusion, by targeting PKA catalytic activity and promoting ERK-dependent degradation, oleuropein effectively attenuates aberrant MITF expression. These findings position oleuropein as a promising modulator of melanoma phenotypic plasticity with potential therapeutic applications.", "source_company": "Jeju National University", "source_org_type": "大学", "row_number": 497, "target_meta": "PKA", "MOA_meta": "其他"}, {"drug_name": "a novel ULK1 inhibitor", "company": "Jeju National University", "org_type": "大学", "target": "ULK1", "modality": "inhibitor", "importance_level": "低", "total_score": 34.5, "institution_score": 25, "track_score": 45, "milestone_score": 35, "field_heat_score": 40, "bonus_score": 0, "brief_reason": "靶向ULK1抑制自噬起始以克服化疗耐药，机制合理但仍处于早期筛选阶段。大学机构+未进入体内研究导致整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6101", "id": "zlXM_5wBX1NQZOEH-LK6", "source_drug_name": "a novel ULK1 inhibitor", "title": "Targeting ULK1 overcomes autophagy-mediated chemoresistance in cancer cell", "abstract_text": "Autophagy is a tightly regulated, lysosomedependent recycling process that preserves energy balance and proteostasis during stress, thereby promoting cell survival. Although chemotherapy aims to eliminate malignant cells, many tumors acquire resistance by engaging prosurvival autophagy. To disable this escape, we targeted Unc51like kinase 1 (ULK1), the initiator of autophagosome biogenesis. We generated a library by modifying reported ULK1 inhibitor scaffolds and screened for blockade of autophagic flux using an LC3GFPmCherry tandem reporter. Western blotting verified ontarget suppression, including phosphorylated ATG13 reduction and p62 accumulation, which nominated a novel lead compound. By treating this compound with standard chemotherapeutics in multiple cancer cell lines, cell death was increased concomitant with the blunted autophagic flux. These data support ULK1 as a tractable node to overcome autophagymediated chemoresistance and rationalize ULK1 inhibition as a combination strategy to deepen chemotherapy responses. Future study will evaluate antitumor efficacy and tolerability in vivo to advance a novel ULK1 inhibitor toward preclinical development.", "source_company": "Jeju National University", "source_org_type": "大学", "row_number": 621, "target_meta": "ULK1", "MOA_meta": "抑制剂"}, {"drug_name": "specific antibody", "company": "Children's Hospital Los Angeles", "org_type": "医院", "target": "COL2A1", "modality": "specific antibody", "importance_level": "低", "total_score": 34.5, "institution_score": 25, "track_score": 45, "milestone_score": 35, "field_heat_score": 40, "bonus_score": 0, "brief_reason": "药物为针对COL2A1的specific antibody，可逆转EMT并增强化疗敏感性，但仅处于功能验证阶段。机构为儿童医院，赛道为ECM靶向+儿科肿瘤，整体开发早期且非热门靶点/模态导致评分较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10831", "id": "RVXM_5wBX1NQZOEH-LO6", "source_drug_name": "specific antibody", "title": "Targeting the extracellular matrix in Wilms tumor", "abstract_text": "Introduction: Wilms tumor (WT) represents approximately 90% of pediatric renal malignancies. While standard treatments are effective for many patients, those with relapse or unfavorable histopathology experience poor survival and severe long-term toxicities. The extracellular matrix (ECM) plays a critical role in driving cancer progression and drug resistance. Our comprehensive profiling of WT revealed type II collagen alpha 1 (COL2A1), absent in normal kidney, to be highly expressed in high-risk tumors, highlighting its potential as a novel biomarker and therapeutic target.\nMethods: We utilized WT cancer stem cell (CSC)-like progenitors, 3D cultures, and patient-derived xenografts (PDXs) with metastatic and chemoresistant phenotypes to investigate COL2A1-mediated signaling. Comparative transcriptomics were performed on WT CSCs cultured on WT-versus normal kidney-derived decellularized ECM. Functional assays assessed epithelial-mesenchymal transition (EMT), tumor suppressor expression, and chemotherapy response following COL2A1 inhibition.\nResults: COL2A1-enriched substrates activated AKT signaling, induced EMT, downregulated tumor suppressors, and promoted chemoresistance. Transcriptomic analysis revealed COL2A1 upregulation alongside its transcriptional regulator SP1, correlating with enhanced tumorigenic pathways and reduced drug sensitivity. Notably, COL2A1 blockade using a specific antibody reversed EMT (i.e., increased cytokeratin and decreased vimentin), restored tumor suppressor expression, and enhanced chemotherapy response.\nConclusions: COL2A1 is a critical ECM component driving therapy resistance in WT. Targeting COL2A1 offers a promising ECM-directed strategy to overcome treatment resistance and improve outcomes in high-risk WT patients. These findings highlight ECM-directed interventions as a new frontier in the treatment of pediatric kidney cancer.", "source_company": "Children's Hospital Los Angeles", "source_org_type": "医院", "row_number": 700, "target_meta": "COL2A1", "MOA_meta": "抗体"}, {"drug_name": "taxanes", "company": "Florida Atlantic University", "org_type": "大学", "target": "beta-tubulin", "modality": "inhibitor", "importance_level": "低", "total_score": 34.5, "institution_score": 25, "track_score": 50, "milestone_score": 30, "field_heat_score": 40, "bonus_score": 0, "brief_reason": "taxanes为经典微管稳定剂，直接靶向beta-tubulin，但本研究聚焦PAK6-LIMK1轴调控细胞骨架以增敏taxanes，而非新药开发。大学机构+机制性基础研究+无明确药物里程碑导致总体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3466", "id": "rlXM_5wBX1NQZOEH-LO6", "source_drug_name": "taxanes", "title": "Target actin-microtubule network integrity to enhance taxane drug-target engagement and chemosensitivity in prostate cancer", "abstract_text": "Taxanes exert anticancer activity by binding beta-tubulin on the luminal surface of microtubules, stabilizing protofilaments, suppressing GTP hydrolysis, and thereby promoting drug-target engagement (DTE) and apoptotic cell death. Access of taxanes to luminal binding sites depends on protofilament organization and microtubule lattice integrity, including entry via plus-end openings, small lattice pores, and stress-induced lattice defects. Because microtubules are tightly coupled to the actin cytoskeleton through crosslinking and mechanical support, we hypothesized that kinases controlling actin-microtubule architecture modulate taxane DTE and sensitivity. We investigated the PAK6-LIMK1 signaling axis in human prostate cancer PC3 and DU145 cells using CRISPR/Cas9 PAK6 knockout and small-molecule inhibitors of PAK6 or LIMK1. Taxane chemosensitivity was quantified by cell viability assays, and cytoskeletal organization and DTE were assessed by immunofluorescence microscopy of F-actin, alpha-tubulin, and the +TIP protein CLIP170. Consistent with prior shRNA data, genetic ablation of PAK6 markedly increased taxane sensitivity in both cell lines. PAK6 loss or pharmacologic inhibition produced concordant, distinctive remodeling of the actin-microtubule network, characterized by loss of dorsal, ventral, and transverse stress fibers and the emergence of crooked, banded microtubule cables, indicating compromised cytoskeletal integrity. These structural changes were accompanied by enhanced taxane-induced microtubule bundling and a robust increase in CLIP170 comet number and size, identifying a novel cytoskeletal signature associated with heightened taxane responsiveness. Similar phenotypes and chemosensitization were observed following LIMK1 inhibition, supporting a shared PAK6-LIMK1 pathway that dually regulates actin and microtubule dynamics. Together, these data suggest that disruption of PAK6-LIMK1 signaling weakens cytoskeletal resilience, facilitates taxane access to intraluminal binding sites, and thereby amplifies DTE and cell killing in prostate cancer cells, nominating this axis as a tractable target to overcome taxane resistance in advanced disease.", "source_company": "Florida Atlantic University", "source_org_type": "大学", "row_number": 769, "target_meta": "β-tubulin", "MOA_meta": "抑制剂"}, {"drug_name": "pId1-SEAP", "company": "University of Alabama at Birmingham", "org_type": "大学", "target": "Id1 promoter", "modality": "plasmid reporter", "importance_level": "低", "total_score": 34.5, "institution_score": 25, "track_score": 40, "milestone_score": 35, "field_heat_score": 45, "bonus_score": 0, "brief_reason": "pId1-SEAP为基于Id1启动子的诊断性质粒报告系统，非治疗性药物，仅用于宫颈癌Id1表达检测；大学早期研究阶段，缺乏热门modality和靶点热度，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6770", "id": "31XM_5wBX1NQZOEH-LO6", "source_drug_name": "pId1-SEAP", "title": "Harnessing Id1 as a Biomarker in a Plasmid Reporter System for Cervical Cancer", "abstract_text": "Introduction: Ten-year cervical cancer (CC) incidence in the U.S. has remained stable despite screening advancements such as HPV testing, suggesting that new CC screening technologies are needed to address stagnant rates. We proposed a diagnostic plasmid for screening that induces expression of a reporter enzyme (secreted embryonic alkaline phosphatase, SEAP) through the control of the cancer-specific inhibitor of differentiation 1 (Id1) promoter sequence. The resulting plasmid (pId1-SEAP) was used to transfect CC cells in vitro and characterize reporter SEAP production based on Id1 expression. Methods and Results: Western Blot and immunohistochemistry were used to establish Id1 expression in cell models and human tissues. Timed transfections in various conditions were used to correlate Id1 and SEAP expression. CC cell lines (HeLa 3.0±0.13, SiHa 2.9±0.27, CaSki 3.1±0.19, all P<0.0001) expressed increased normalized baseline Id1 compared to non-cancer 3T3 fibroblasts (1.0±0.0). In a microarray of CC tissues, normal samples had mean Id1 staining value of 3E4±3E4, while early- and late-stage cancers had increased mean Id1 staining (3E5±1E5 P<0.0001 and 2E5±1E5 P=0.0002, respectively). HeLa and SiHa lines produced increased normalized SEAP amounts with pId1-SEAP (0.63±0.25 and 0.50±0.10, P<0.05) compared to 3T3 cells with pId1-SEAP (0.16±0.058). Id1 and SEAP expression were strongly correlated (Pearson’s r=0.99, P=0.012). As few as 12,500 pId1-SEAP plasmid-exposed HeLa cells co-cultured with naïve cells resulted in an increased SEAP value (3E4±3E3 P=0.004) compared to background level (1E4±4E2). Conclusions and Future Directions: pId1-SEAP can transfect CC cells to produce SEAP proportionally to endogenous Id1 expression, demonstrating its potential for future diagnostic tests for CC. These data support further studies to characterize pId1-SEAP function in 3-D tissue models and in vivo animal models, towards the development of a home-based approach to screen for cervical cancer using Id1 expression as a biomarker.", "source_company": "University of Alabama at Birmingham", "source_org_type": "大学", "row_number": 807, "target_meta": "ID1", "MOA_meta": "其他"}, {"drug_name": "20(OH)D₃", "company": "The University of Alabama at Birmingham", "org_type": "大学", "target": "VDR及其他核受体（LXR, AhR, ROR）", "modality": "other", "importance_level": "低", "total_score": 34.5, "institution_score": 25, "track_score": 45, "milestone_score": 35, "field_heat_score": 40, "bonus_score": 0, "brief_reason": "20(OH)D₃为非钙化维生素D3羟基衍生物，主要通过VDR及其他核受体发挥抗黑色素瘤作用，与vemurafenib联用显示协同抑制肿瘤生长。大学机构、非热门modality、仅体外+初步体内研究且单药活性有限，导致整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1931", "id": "ep7ECZ0BZznHJdntvNYd", "source_drug_name": "20(OH)D₃", "title": "Targeting human melanoma growth with non-calcemic vitamin d3 hydroxyderivative: A synergistic approach with vemurafenib", "abstract_text": "Background: Melanoma remains a major clinical challenge due to its resistance to current targeted therapies, emphasizing the need for new preventive and therapeutic strategies. The vitamin D receptor (VDR) and its ligands are promising, low-toxicity targets. Our team has discovered an alternative, noncanonical vitamin D-metabolic pathway initiated by CYP11A1, generating hydroxyderivatives such as 20(OH)D₃ with antioxidative, photoprotective, and anticancer activities through VDR and other nuclear receptors (LXR, AhR, ROR). We hypothesize that 20(OH)D₃, alone or combined with vemurafenib (VEM), can inhibit melanoma tumorigenic behavior through VDR-dependent and independent mechanisms.\nMethods: In vitro studies used migration, CFU, and PrestoBlue viability assays on melanoma lines (WM3960, WM1366, WM3942, WBM550). Spheroid assays utilized 3D culture and TUNEL staining to assess apoptosis. In vivo efficacy was evaluated in nude mice implanted with either wild-type (WT) or VDR-knockout (VDR⁻/⁻) WM164 (BRAFV600E) melanoma cells. Mice received vehicle, 20(OH)D₃ VEM, or combination therapy three times weekly. Tumor growth and necrosis were monitored, and protein expression was analyzed by Western blotting.\nResults: Cell migration assays demonstrated that the treatment with novel vitamin D₃ derivatives markedly inhibited the migratory capacity of WM3960 PDX melanoma cells. CFUs further confirmed a significant reduction in melanoma cell growth across several melanoma cell lines. Viability assay revealed decreased fluorescence intensity in treated cells relative to controls, indicating reduced metabolic activity, viability, and proliferation. No apoptosis was detected using the TUNEL System, suggesting that the observed effects were primarily cytostatic rather than apoptotic. In vivo, WT WM164 xenografts treated with the combination of 20(OH)D₃ and VEM exhibited the strongest tumor suppression, followed by VEM monotherapy, whereas 20(OH)D₃ alone had minimal impact. In VDR⁻/⁻ tumors, both VEM and combination treatments achieved comparable inhibition, indicating both VDR-dependent and independent mechanisms of action. Western blot confirmed synergistic downregulation of phospho AKT, ERK1/2, and NF-κB signaling pathways in combination-treated tumors, consistent with enhanced suppression of oncogenic signaling. Notably, male mice displayed greater sensitivity to the combination therapy compared with females.\nConclusion: The non-calcemic vitamin D₃ derivative 20(OH)D₃, especially when combined with vemurafenib, inhibits human melanoma growth by blocking oncogenic signaling pathways, independent of apoptosis. Due to its natural origin, safety profile, and pathway selectivity, 20(OH)D₃ has strong potential as a preventive and therapeutic agent against melanoma progression and metastasis.", "source_company": "The University of Alabama at Birmingham", "source_org_type": "大学", "row_number": 961, "target_meta": "VDR,LXR,AHR", "MOA_meta": "其他"}, {"drug_name": "ouabain", "company": "Bar-Ilan University", "org_type": "大学", "target": "Na+/K+-ATPase", "modality": "inhibitor", "importance_level": "低", "total_score": 34.5, "institution_score": 25, "track_score": 45, "milestone_score": 35, "field_heat_score": 40, "bonus_score": 2, "brief_reason": "Ouabain为经典Na+/K+-ATPase抑制剂（心脏苷类），摘要显示其在体外对胶质母细胞瘤干细胞具有抗肿瘤和senolytic双重作用，但仅为大学基础研究，无明确临床开发进展。机构非药企、preclinical阶段且为老药新用、脑瘤领域未满足需求有限导致总体评分较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/708", "id": "GZ7M_5wBZznHJdnt_W7O", "source_drug_name": "ouabain", "title": "Ouabain exerts both anti-tumor and senolytic effects in brain cancer stem and tumor cells", "abstract_text": "Glioblastoma (GBM) and diffuse intrinsic pontine glioma (DIPG) are highly aggressive brain tumors with dismal prognoses. These tumors contain therapy-resistant cancer stem cells (CSCs) that drive tumor progression and relapse. Standard treatments such as radiation and temozolomide (TMZ) induce senescence in a subset of tumor cells, generating a persistent, treatment-refractory population. Senolytic agents that selectively eliminate senescent cells may overcome this resistance. Here, we investigated the anti-tumor and senolytic effects of the cardiac glycoside ouabain in glioblastoma stem cells (GSCs), DIPG stem cells, and glioma cell lines. Neurosphere formation and transwell assays were used to assess self-renewal and migration, and senolytic activity was examined in TMZ-treated cells using β-galactosidase staining. RT-PCR quantified stemness-associated gene expression.Ouabain inhibited the self-renewal of GSCs and DIPG stem cells in a dose-dependent manner and reduced their migratory capacity. TMZ pre-treatment sensitized GSCs to ouabain, resulting in a more pronounced suppression of neurosphere formation and an enhanced inhibition of migration. Ouabain decreased the expression of stemness and EMT-related genes, including SOX2, YKL-40, OCT4, and NANOG.In addition, ouabain selectively eliminated TMZ-induced senescent cells in both glioma cell lines and differentiating GSCs. Together, these findings demonstrate that ouabain exerts dual anti-tumor and senolytic effects in GBM and DIPG cells by suppressing CSC stemness, migration, and eliminating senescent, stem-like populations. These combined effects highlight ouabain as a potential therapeutic strategy for targeting treatment-resistant cells in malignant gliomas.", "source_company": "Bar-Ilan University", "source_org_type": "大学", "row_number": 1144, "target_meta": "Na/K-ATPase", "MOA_meta": "抑制剂"}, {"drug_name": "black soybean exosomes", "company": "Kobe University Graduate School of Medicine", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 34.5, "institution_score": 25, "track_score": 40, "milestone_score": 35, "field_heat_score": 45, "bonus_score": 0, "brief_reason": "黑大豆来源的植物exosomes，靶点和具体抗癌机制未明确披露，仅显示体外对胰腺癌和结肠癌细胞的增殖抑制及放疗增敏作用。大学机构、非主流热门赛道、仅preclinical体外数据导致整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/2865", "id": "IJ7M_5wBZznHJdnt_W7O", "source_drug_name": "black soybean exosomes", "title": "Plant-derived exosomes from black soybeans for combatting pancreatic and colon cancer cells", "abstract_text": "Background: Plant-derived dietary exosomes are biocompatible granular vesicles that are considered safe and have been increasingly reported to exert beneficial effects on the human body. We independently developed a novel method for isolating food-derived exosomes from black soybeans and demonstrated their therapeutic efficacy against pancreatic and colon cancer cells.\nMaterials and methods: We developed a technique to efficiently isolate exosomes from freshly harvested black soybean pods. The size and morphology of the exosomes were evaluated using nanoparticle tracking analysis and transmission electron microscopy (TEM). The antitumor effects were evaluated by assessing the cell proliferation inhibitory effects using WST/MTT assays with human pancreatic cancer MIAPaca-2 and human colon cancer HCT116 cells. The efficacies of different exosome conditioning methods, such as freezing, boiling, boiling in salt, or immediate extraction, were compared in terms of their cell proliferation inhibitory effects. The radiosensitizing effects were also investigated using a colony-forming assay. The extent and frequency of DNA damage were determined using γH2AX staining, a marker for DNA damage, between four groups: control, black soybean exosomes alone, radiation alone, and a combination of both.\nResults: The mean size of the exosomes was less than 200 nm. Absorption of the exosome were observed in very high frequency in MIApaca-2 cells. The exosomes obtained from approximately 20 black soybeans exhibited much higher tumor growth inhibitory effects than the solution of black soybeans without exosomes. The exosomes also showed radiosensitizing effect in response to 6 Gy of ionizing radiation.\nConclusions: These findings together represent that the plant-derived dietary exosomes from black soybeans may have potential to be a novel strategy for cancer cell growth inhibition and radiosensitization.", "source_company": "Kobe University Graduate School of Medicine", "source_org_type": "大学", "row_number": 1147, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "gold nanorods", "company": "Aga Khan University Hospital", "org_type": "医院", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 34.5, "institution_score": 25, "track_score": 45, "milestone_score": 35, "field_heat_score": 40, "bonus_score": 0, "brief_reason": "gold nanorods作为纳米材料用于增强放疗敏感性，未明确特定靶点，属其他模态；机构为医院学术型，赛道非热门前沿，体外低剂量放疗增强凋亡属preclinical早期探索，无显著里程碑。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3957", "id": "KJ7M_5wBZznHJdnt_W7O", "source_drug_name": "gold nanorods", "title": "Redox modulation by gold nanorods enhances radiosensitivity in MOLT 4 cells", "abstract_text": "Gold nanoparticles have gained increasing interest because of their unique optical properties. Among different shapes of nanoparticles, gold nanoparticles (Au-NPs) with non-spherical shape, such as gold nanorods (Au-NR), are gaining particular attention for various applications because of their facile synthesis and modification. They can be conjugated with different molecules for biomedical applications, such as tumor imaging and therapy. Previously, we have shown that small sized Au-NPs possess distinct effects depending on the treatment modality; they protect against x-ray induced apoptosis while enhancing apoptosis induced by ultrasound and helium based cold atmospheric plasma. Therefore, this study is intended to investigate the effects of Au-NR, on x-ray (2.5 Gy) induced apoptosis as well as mediating molecular pathways in MOLT 4 cells in-vitro. The effect of Au-NR on x-ray induced apoptosis was determined by observing the changes in intracellular reactive oxygen species (ROS) formation and apoptotic signalling pathways. The results indicate that cells pre-treated with 10 nm size of Au-NR at a dose of 0.1 and 0.5 μg significantly enhanced apoptosis. Typical morphological changes were observed by using Giemsa staining which shows the enhanced apoptotic cell death in combination treatment. Loss of mitochondrial membrane potential, glutathione and intracellular calcium ion level was significantly enhanced; observed by using flow cytometry. Furthermore, western blot analysis was employed to determine the expression of caspase-3, and Bcl-2 family proteins. In this study we have shown for the first time that in combination treatment, Au-NR significantly enhanced the low dose of x-ray-induced apoptotic cell death. Our finding indicates that the combination treatment of cancer will be emerged as a critical approach to achieve remarkable anticancer effects.", "source_company": "Aga Khan University hospital\nAga Khan University Hospital", "source_org_type": "医院", "row_number": 1151, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "DNA damage-inducing anticancer drugs", "company": "University of Bath", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 34, "institution_score": 25, "track_score": 40, "milestone_score": 35, "field_heat_score": 45, "bonus_score": 0, "brief_reason": "该研究针对DNA损伤类抗癌药物的非肿瘤细胞效应，揭示其诱导成纤维细胞衰老和促肿瘤微环境重塑的机制，但未披露具体药物或靶点。机构为大学且仅为基础研究机制探讨，整体开发价值和里程碑意义较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8145", "id": "VJ7ECZ0BZznHJdntvNYd", "source_drug_name": "DNA damage-inducing anticancer drugs", "title": "DNA damaging therapies induce a pro-tumorigenic fibroblast phenotype", "abstract_text": "There is growing evidence that anticancer therapies not only target tumour cells but also reshape the tumour microenvironment, paradoxically enabling fibroblasts to acquire a pro-tumorigenic phenotype. These fibroblasts are characterised by an altered secretome and extensive extracellular matrix (ECM) remodelling, which promote therapy resistance and tumour progression.\nIn this study, we demonstrate that DNA damage-inducing anticancer drugs drive normal fibroblasts towards a fibrosis- and cancer-associated fibroblast (CAF)-like phenotype. Using 3D cell-derived ECM deposition assays, we show that treatment of both normal fibroblasts and CAFs stimulates the formation of a more anisotropic ECM with enlarged pores. This remodelled ECM enhances cancer cell adhesion and proliferation, while unexpectedly reducing migration across the matrix. In contrast, the soluble secretome does not affect cancer cell proliferation but significantly increases chemotactic migration towards the therapy-exposed fibroblasts.\nGene expression profiling by RNA sequencing combined with 2D and 3D in vitro analyses, reveals that prolonged drug exposure induces fibroblast senescence, marked by upregulation of β-galactosidase, IL6, CDKN1A, and CDKN2A expression. The therapy-induced senescent fibroblasts also display features of a myofibroblast-like CAF (myCAF) phenotype, including enhanced contractility and increased expression of ACTA2, PDGFRA, MMPs, TIMPs, and extracellular matrix components such as collagens, vitronectin, and VCAM. We have previously shown that myCAFs can promote in vivo growth and metastasis, underscoring their critical role in tumour progression.\nOur findings suggest that therapy-induced senescence in fibroblasts may create a permissive microenvironment for tumour progression.", "source_company": "University of Bath", "source_org_type": "大学", "row_number": 615, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "partially hydrolyzed guar gum", "company": "The Hormel Institute, University of Minnesota", "org_type": "研究机构", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 34, "institution_score": 25, "track_score": 40, "milestone_score": 35, "field_heat_score": 45, "bonus_score": 0, "brief_reason": "partially hydrolyzed guar gum (PHGG) 为水溶性膳食纤维补充剂，无明确药物靶点，机制通过调节肠道菌群及SCFAs影响乳腺癌小鼠模型。机构为大学研究机构、处于基础研究阶段且非热门肿瘤药物赛道，导致整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6717", "id": "4FXM_5wBX1NQZOEH-LO6", "source_drug_name": "partially hydrolyzed guar gum", "title": "PHGG supplementation modulates gut microbiome metabolites and breast cancer progression", "abstract_text": "Short-chain fatty acids (SCFAs) are linked to improved anti-tumor immune responses and reduced breast cancer risk. Isoflavones in soybean-based (SB) high fiber diets may block fiber’s advantages by triggering immunosuppression. We investigated the effect of SB diet, combined with partially hydrolyzed guar gum (PHGG) supplementation, on triple negative E0771 mammary tumor growth in mice fed AIN93G control or SB diet. Some SB-fed mice received PHGG or maltodextrin (MDX) control in drinking water. We found that SB diet increased tumor burden, and both MDX and PHGG revered the increase. Fecal microbiota transplants (FMTs) were prepared from the AIN93G, SB, SB+PHGG, and SB+MDX fed mice, and transferred to antibiotic-treated hosts fed AIN93G diet. Tumor burden was similar in hosts receiving FMT from AIN93G, SB, or SB+MDX donors, suggesting that SB diet did not increase mammary tumorigenesis through changes in the gut microbiome but perhaps directly by affecting immune cells in the tumor microenvironment. Mice receiving FMT from SB+PHGG fed donors exhibited significantly reduced tumor burden. To further investigate whether cellulose in AIN93G diet affected PHGG’s ability to reduce mammary tumorigenesis, compared with MDX, we fed mice cellulose-free AIN93G diet. In this setting, PHGG reduced tumorigenesis compared with MDX. However, PHGG increased fecal SCFAs both in cellulose containing and cellulose-free AIN93G diet fed mice. Further, PHGG-supplemented mice exhibited significantly increased FFAR3 expression in CD4+ T cells in the spleen. Our findings indicate that PHGG reduces mammary tumorigenesis in mice fed fiber-deficient diet, and the effect is likely mediated through the gut microbiome.", "source_company": "The Hormel Institute, University of Minnesota", "source_org_type": "研究机构", "row_number": 808, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "spermine", "company": "University of Miami Miller School of Medicine", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 33.5, "institution_score": 25, "track_score": 40, "milestone_score": 35, "field_heat_score": 45, "bonus_score": 0, "brief_reason": "spermine为天然多胺分子，非药物形式，未披露明确药物靶点，仅在基础研究中显示增强胶质母细胞瘤氧化磷酸化作用。大学机构+早期机制探索阶段，整体开发价值和热度有限。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9209", "id": "aVXM_5wBX1NQZOEH-LG5", "source_drug_name": "spermine", "title": "Spermine enhances oxidative phosphorylation independently of translation in glioblastoma", "abstract_text": "Glioblastoma (GBM) is the most aggressive and lethal primary malignant brain tumor, with a mean survival of only 15 months, emphasizing the need for novel therapeutic strategies. Polyamines, small positively charged molecules necessary for cell proliferation, are frequently dysregulated in multiple cancer types, including GBM. Despite this, their distinct role in tumorigenesis has not been well characterized. There are three major polyamines: putrescine, spermidine, and spermine. Putrescine is converted into spermidine, which is further converted into spermine. The role of spermidine has been well defined, as it serves as a precursor for eIF5a-deoxyhypusine, which undergoes hypusination to promote translation of growth factors. Spermine Synthase (SMS), the enzyme that catalyzes the conversion of spermidine to spermine, is upregulated in high-grade gliomas. Preliminary data suggests that SMS is necessary for GBM tumor development and growth, supporting the idea that polyamine metabolism can be a targetable vulnerability in GBM. However, the specific role of spermine, the product of SMS, in GBM remains unknown. We hypothesize that spermine has distinct, non-redundant cellular functions in GBM and aim to elucidate its role using a CRISPR-mediated autochthonous mouse model of GBM. In this model, a plasmid encoding Cas9 and guide RNAs targeting the tumor suppressors PTEN, P53, and NF1 along with polyamine-related genes of interest are introduced into mouse embryos via intrauterine electroporation (IUE), leading to GBM tumor development. Utilizing this system, we have found that SMS knockout (KO) significantly inhibits GBM growth in vitro and in vivo. Interestingly, supplementing physiological concentrations of spermine failed to restore cell viability and oxidative phosphorylation (OCR) in SMS KO cells, while wild-type cells exhibited a robust increase in OCR upon spermine supplementation. Further investigation revealed spermine enhances OCR independently of translation, suggesting that it may function through a post-translational modification (PTM) mechanism. Ongoing studies aim to further characterize the role of SMS and spermine in GBM metabolism and tumor growth. These findings suggest that spermine is a critical regulator of GBM development and progression and may offer a novel metabolic target for therapeutic intervention.", "source_company": "University of Miami Miller School of Medicine", "source_org_type": "大学", "row_number": 13, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "DMH1", "company": "University of Massachusetts Medical School", "org_type": "大学", "target": "BMP signaling (ALK1/ALK2/ALK3 receptors)", "modality": "inhibitor", "importance_level": "低", "total_score": 33.5, "institution_score": 25, "track_score": 40, "milestone_score": 35, "field_heat_score": 45, "bonus_score": 0, "brief_reason": "DMH1为pan-BMP信号小分子抑制剂，主要靶向ALK1/2/3受体，在子宫内膜癌细胞系中显示抑制pSMAD和细胞活力作用；但来自大学机构的工具化合物性质，preclinical体外水平，无临床开发迹象，赛道非热门导致总体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1877", "id": "K1XM_5wBX1NQZOEH-LG5", "source_drug_name": "DMH1", "title": "Investigating BMP signaling as a therapeutic vulnerability in endometrial cancer", "abstract_text": "Introduction: Endometrial cancer (EC) is the sixth most common malignancy in women worldwide, with nearly 400,000 new cases annually. Aggressive EC subtypes are associated with poor prognosis, highlighting the urgent need for mechanism-based therapies. Emerging evidence implicates Bone Morphogenetic Protein (BMP) signaling as a driver of EC progression. Approximately 5% of EC tumors harbor ACVR1(R206H) gain-of-function mutations, which overactivate BMP signaling. Our goal is to define the prevalence, sources, and functional consequences of BMP activation in EC and assess whether pharmacologic inhibition suppresses tumor growth.\nMethods: Phospho-SMAD1/5/8 (pSMAD) levels were quantified in EC tumors and normal endometrium to assess BMP pathway activation. Genomic and transcriptomic datasets were analyzed to identify ACVR1 mutations and BMP ligand expression associated with patient survival. Functional studies were conducted in multiple EC cell lines using the pan-BMP inhibitor DMH1. pSMAD was measured by western blot, downstream BMP target gene transcription (ID1/ID3) was assessed by qPCR, and cell viability was evaluated to determine the effect of BMP inhibition on tumor cell survival and proliferation.\nResults: pSMAD levels were elevated in over half of EC tumors compared with low-to-moderate levels in normal endometrium. High expression of BMP ligands GDF6 and BMP7 correlated with poor overall survival. DMH1 selectively reduced pSMAD without affecting total SMAD, downregulated ID1 and ID3, and decreased viability in Ishikawa, HEC1A, and AN3CA cells within 24 hours, demonstrating that BMP signaling is required to sustain tumor growth and proliferation.\nConclusions: BMP signaling is recurrently activated in EC through receptor mutation and ligand overexpression, promoting aggressive tumor behavior. Pharmacologic inhibition reverses downstream transcriptional activity and suppresses tumor cell viability, establishing BMP signaling as an actionable therapeutic vulnerability. These findings support the development of BMP-directed strategies to improve clinical outcomes in patients with endometrial cancer.", "source_company": "University of Massachusetts Medical School", "source_org_type": "大学", "row_number": 339, "target_meta": "ALK3,ALK2,ACVRL1", "MOA_meta": "抑制剂"}, {"drug_name": "an NRF2 activator", "company": "Aga Khan University", "org_type": "大学", "target": "NRF2", "modality": "inhibitor", "importance_level": "低", "total_score": 33.5, "institution_score": 25, "track_score": 45, "milestone_score": 30, "field_heat_score": 40, "bonus_score": 3, "brief_reason": "NRF2激活剂通过诱导paraptosis样非凋亡细胞死亡针对氧化应激脆弱性克服结直肠癌凋亡耐药，但仅为大学体外机制研究。机构非商业公司、开发阶段为preclinical早期、无明确药物分子导致整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4604", "id": "M1XM_5wBX1NQZOEH-LG5", "source_drug_name": "an NRF2 activator", "title": "Oxidative stress-mediated non-apoptotic, non-autophagic cell death: A mechanistically distinct strategy to overcome resistance in colorectal cancer cells", "abstract_text": "Cancer remains a leading cause of mortality worldwide, with therapeutic failure often driven by apoptosis resistance a major hurdle that limits the efficacy of conventional anticancer therapies. Targeting alternative, caspase-independent cell death pathways has emerged as a promising strategy to overcome this resistance. In this study, we evaluated the effects of two mechanistically distinct small molecules a BCL-XL inhibitor and an NRF2 activator on colorectal cancer cell lines to investigate their ability to induce non-apoptotic cell death. Both agents reduced cell viability in a dose- and time-dependent manner. The NRF2 activator triggered cytoplasmic vacuolation at lower concentrations, characteristic of paraptosis, accompanied by endoplasmic reticulum (ER) dilation, oxidative stress, and downregulation of Alix, a key inhibitor of paraptosis. This mode of cell death required de novo protein synthesis and was independent of caspase activation, PARP cleavage, and DNA fragmentation. In contrast, the BCL-XL inhibitor displayed a dose-dependent switch between vacuolation-induced cell death and classical apoptosis, marked by phosphatidylserine externalization and DNA fragmentation. These findings underscore oxidative stress-mediated, vacuolation-associated non-apoptotic cell death as a mechanistically distinct and therapeutically relevant modality for targeting apoptosis-resistant cancer cells. This approach may pave the way for innovative cancer therapies that exploit tumor redox vulnerabilities while bypassing traditional cell death pathways.", "source_company": "Aga Khan University", "source_org_type": "大学", "row_number": 343, "target_meta": "Nrf2", "MOA_meta": "抑制剂"}, {"drug_name": "anti-mouse CD25 antibody", "company": "Fox Chase Cancer Center", "org_type": "医院", "target": "CD25", "modality": "antibody", "importance_level": "低", "total_score": 33.5, "institution_score": 25, "track_score": 40, "milestone_score": 35, "field_heat_score": 45, "bonus_score": 0, "brief_reason": "anti-CD25抗体靶向CD25用于耗竭Tregs，在老龄小鼠黑色素瘤模型中显著降低肺转移，机制明确但仅为工具抗体。机构为医院/研究型癌症中心、非商业开发，赛道非热门临床转化方向，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10661", "id": "f1XM_5wBX1NQZOEH-LG5", "source_drug_name": "anti-mouse CD25 antibody", "title": "Aging promotes liver and lung melanoma metastasis via tissue-infiltrating Tregs", "abstract_text": "Metastasis is the leading cause of melanoma-related deaths, yet its age-related mechanisms remain poorly understood. This gap stems partly from reliance on young mouse models (~8 weeks old, equivalent to 20 human years) in most studies. Additionally, research has largely focused on lung metastasis, even though melanoma often spreads to other sites like the liver, which is notably more resistant to immune checkpoint inhibitors (ICIs).Using syngeneic melanoma cells, we optimized intravenous (IV) injections to model lung colonization and developed a novel liver colonization model using hydrodynamic tail vein injections. Tumor cells were injected into young (8 weeks) and aged (12-16 months) male C57BL/6 mice. Spleen, lungs, and liver were harvested to assess immune infiltration of lymphocyte and myeloid populations via flow cytometry. Hematoxylin and eosin (H&E) and immunohistochemistry (IHC) staining were used to quantify metastases and examine spatial immune cell locations. Upon observation that regulatory T cells (Tregs) increased consistently in aged mice in both lung and liver metastatic sites, we treated additional aged cohorts with either anti-mouse CD25 antibody, which we show decreased Tregs while not changing CD3+, CD4+ or CD8+ T cell infiltration, or an IgG control (200 μg/mouse, intraperitoneally) to evaluate the role of Tregs and in metastasis.Aging significantly increased melanoma colonization in both the lungs and liver compared to young mice. Analysis of common changes in the immune microenvironment of both the lung and the liver revealed elevated Treg infiltration in both metastatic sites of aged mice. Notably, Tregs were not elevated in the pre-metastatic niche, suggesting an age- and tumor-specific mechanism of immune suppression. Depletion of Tregs in aged mice using anti-CD25 antibody significantly reduced lung metastases compared to IgG controls. Moreover, depletion of Tregs decreased secretion of TGF-β and the number of myeloid cells in metastatic sites and increased the number of NK1.1+ NK cells, CD4+ and CD8+ T cells.Our findings indicate that age-associated Treg infiltration promotes metastasis to the lung and liver, suggesting that targeting Tregs could offer a promising approach to mitigate age-related metastatic progression in melanoma.", "source_company": "Fox Chase Cancer Center", "source_org_type": "医院", "row_number": 394, "target_meta": "IL-2Rα", "MOA_meta": "抗体"}, {"drug_name": "BW813U", "company": "Marshall University", "org_type": "大学", "target": "ChAT", "modality": "inhibitor", "importance_level": "低", "total_score": 33.5, "institution_score": 25, "track_score": 35, "milestone_score": 40, "field_heat_score": 40, "bonus_score": 0, "brief_reason": "BW813U为ChAT小分子抑制剂，针对吸烟相关肺腺癌通过抑制肿瘤血管生成发挥抗肿瘤作用。大学机构、非热门靶点与modality、仅动物模型及体外数据导致整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1945", "id": "7FXM_5wBX1NQZOEH-LG6", "source_drug_name": "BW813U", "title": "Choline Acetyltransferase: A novel drug target in lung adenocarcinoma patients who are exposed to tobacco smoke", "abstract_text": "Purpose of the study: Lung cancer is not a single disease entity; it represents a spectrum of malignancies. Out of these lung adenocarcinoma (LUAD) accounts for about 65% of all lung cancers and shows a strong etiological correlation with smoking. Clinical studies show that about 30% of LUAD patients continue to smoke after being diagnosed with lung cancer. In addition, many others are exposed to nicotine via secondhand smoke and smoking cessation devices. Nicotine, the addictive component of tobacco smoke, accelerates the growth of human LUADs via the by nicotinic acetylcholine receptors (nAChRs) on target cells. The first-line therapy for LUAD patients involves the administration of tyrosine kinase inhibitors (TKIs) targeting EGFR, ALK, MET kinases. Such targeted therapies show potent anti-cancer activity in non-smokers and never smokers but show poor efficacy in patients who continue to smoke after their diagnosis. The primary objective of our research is to evaluate the potential of choline acetyltransferase (ChAT, the enzyme which synthesizes acetylcholine) as a drug target for LUAD in smokers. We evaluated the anti-neoplastic activity of BW813U (small molecule inhibitor of ChAT) in LUADs associated with moderate-heavy smoking history. We also investigated the anti-angiogeneic activity of BW813U (as a molecular mechanism underlying its growth-inhibitory effects) LUAD.\nExperimental procedures. Primary human microvascular endothelial cells from the lung (HMEC-L) were used for all the experiments. These cells were used between passage 3-7. The anti-angiogenic activity of BW813U was measured in cell culture models by using the “MATRIGEL ASSAY”. The results obtained from the “MATRIGEL ASSAY” were confirmed using chicken chorioallantoic membrane (CAM) angiogenesis experiments. Finally, the anti-tumor activity of BW813U was measured in vivo by using xenograft model systems in SCID mice. Our studies also investigated the signaling pathways underlying the anti-angiogenic activity of BW813U, using chemical inhibitors and siRNA methodology.\nResults: BW813U robustly suppressed angiogenesis in Matrigel assays and CAM model systems. The administration of BW813U potently decreased the growth rate of H838 tumors xenotransplanted in SCID mice. Immunohistochemical staining experiments revealed that the anti-tumor activity of BW813U was correlated with decrease of CD31 angiogenic biomarker in H838 tumor sections. The anti-angiogenic activity of BW813U was mediated by the alpha7-nAChR pathway and involved the nitric oxide pathway. Taken together, our studies show that ChAT may be a valuable drug target for the therapy of LUAD.\nConclusions: ChAT antagonists like BW813U decrease the growth of LUAD by suppressing tumor angiogenesis.", "source_company": "Marshall University", "source_org_type": "大学", "row_number": 473, "target_meta": "CHAT", "MOA_meta": "抑制剂"}, {"drug_name": "anti-HER2/neu antibody", "company": "George Washington University School of Medicine and Health Sciences", "org_type": "大学", "target": "HER2", "modality": "antibody", "importance_level": "低", "total_score": 33.5, "institution_score": 25, "track_score": 60, "milestone_score": 20, "field_heat_score": 50, "bonus_score": 0, "brief_reason": "药物为针对HER2的抗体，用于HER2+乳腺癌研究，但仅为大学基础研究，探讨抗生素对疗效的负面影响，无新药开发进展。机构非企业、开发阶段为动物模型preclinical且非药物推进，导致总体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5340", "id": "c1XM_5wBX1NQZOEH-LK6", "source_drug_name": "anti-HER2/neu antibody", "title": "Antibiotics blunt the innate immune mechanisms underlying HER2+ breast cancer therapy efficacy", "abstract_text": "Cancer patients are especially vulnerable to infections. About 20-60% of patients may receive antibiotics at some stage during their treatment, including perioperative care and neutropenic periods. Retrospective studies indicate that antibiotics can negatively affect outcomes in various cancers. HER2+ breast cancer (BC) patients often receive targeted treatments such as anti-HER2 antibodies and/or small-molecule tyrosine kinase inhibitors (TKI), which remain understudied in this context. Published work indicates that HER2+ BC patients experience more severe reductions in survival following antibiotic exposure than HER2-negative cases. Although this antibiotic effect is thought to result from host microbiota disruptions, the precise mechanisms remain unclear. To understanding how antibiotics specifically affect HER2 therapies, we examined how antibiotics influence responses to HER2-targeted therapies using an orthotopic HER2+ BC mouse model, administering an oral broad-spectrum antibiotic cocktail (ABX) to deplete the microbiota or water (H2O) as a control, and employing an anti-HER2 antibody (anti-HER2/neu) or the TKI neratinib. While antibiotic treatment alone did not influence tumor growth, it notably impaired responses to HER2 therapies. To simulate clinical scenarios, we administered oral ciprofloxacin (cipro) or amoxicillin/clavulanic acid (am/clav), common antibiotics used for cancer patients, alongside neratinib, which was most affected by ABX. Cipro reproduced the ABX effect, completely blocking neratinib response, while am/clav caused a partial impairment. Next, we characterized immune cells in tumors and the bloodstream after HER2-targeted therapy by spectral flow cytometry. In H2O mice, both HER2 therapies led to immune remodeling of the tumors, with reduced tumor-associated neutrophils and macrophages, and increased NK, CD8+, and CD4+ T cell infiltration. In contrast, NK cells were systemically decreased in untreated ABX mice compared with H2O mice and did not recover after therapy, explaining the failure to recruit these cells to the tumor site in ABX mice. To assess the role of NK cells in therapy efficacy, we depleted NK cells with an anti-asialo-GM1 antibody before and during HER2 therapies. As expected, NK cell depletion abolished the anti-HER2 response but also led to a partial reduction in neratinib efficacy, hinting that neratinib engages tumor-extrinsic innate immune mechanisms influenced by antibiotics. Overall, our findings show that antibiotic-induced disruption of the gut microbiota hampers HER2+ BC therapy by impairing the immune response both systemically and within the tumor microenvironment.", "source_company": "George Washington University School of Medicine and Health Sciences", "source_org_type": "大学", "row_number": 561, "target_meta": "HER2", "MOA_meta": "抗体"}, {"drug_name": "a novel compound", "company": "Atrium Health Wake Forest Baptist Comprehensive Cancer Center", "org_type": "医院", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 33.5, "institution_score": 25, "track_score": 40, "milestone_score": 35, "field_heat_score": 45, "bonus_score": 0, "brief_reason": "药物靶点和具体机制未披露，仅显示在骨肉瘤模型中诱导巨噬细胞向M1极化转变；机构为医院/学术中心、处于工具验证+初步体内观察阶段，整体开发价值和热度有限。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10904", "id": "ZJ7ECZ0BZznHJdntvNYd", "source_drug_name": "a novel compound", "title": "Development of a CyTOF panel for macrophage polarization and functional assessment under treatment conditions", "abstract_text": "Purpose: Tumor associated macrophages (TAMs) are prevalent in the sarcoma tumor microenvironment, and often contribute to immune suppression, angiogenesis, and tumor progression. TAMs exhibit a spectrum of polarization states, ranging from anti-tumor (M1) to tumor-supportive (M2) functions. Mass cytometry (CyTOF) enables high-dimensional single-cell profiling, making it ideal for dissecting the presence and abundance of various macrophage phenotypes within a tumor. This study aimed to design and validate a CyTOF panel targeting macrophages and associated immune markers, to characterize macrophage polarization states and evaluate treatment induced changes in macrophage subtypes.\nMethods:  A mouse macrophage-focused CyTOF panel was developed comprised of 40 markers, including lineage markers, activation markers, and cytokine-associated proteins relevant to M1/M2 phenotypes and other immune cell populations. For optimization of antibody titration and staining conditions, macrophage polarization was performed in vitro using the commercially available mouse-derived macrophage cell line RAW 264.7. Macrophage polarization states were induced under standard conditions: M1: LPS + IFN-γ and M2a: IL-4 + IL-13, M2b- OVA, Anti-OVA IgG, M2c- IL-10, and M2d-NECA stimuli. Following validation, the panel was applied to a mouse model of orthotopically implanted osteosarcoma cells treated with a novel compound to quantify the TAM polarization and associated immune networks. Tumor tissue samples were dissociated into single cell suspensions, stained using the CyTOF panel, and analyzed using dimensionality reduction (UMAP) and clustering algorithms.\nResults: The 40-marker CyTOF panel was successfully used to identify and characterize macrophage subtype populations in vitro as well as in mouse xenograft tumors. In vitro polarization of mouse RAW264.7 cells showed distinct phenotypic clusters corresponding to M1 and M2 subtypes. These results also enabled effective antibody titration. Treatment of orthotopically implanted osteosarcoma tumors with the novel compound resulted in increased expression of M1 markers and a reduction in M2-associated markers compared to vehicle control, indicating a shift in macrophage polarization induced by this compound.\nConclusion: The developed CyTOF panel provides a robust platform for high-resolution analysis of macrophage polarization and treatment-induced phenotypic changes, offering more detailed investigation of immune modulation strategies. This panel could be applied as a tool for future investigations focused on macrophage subpopulations and their functional roles and will allow for further dissection of the tumor immune microenvironment, advancing the understanding of immunological variability in response to treatment.", "source_company": "Atrium Health Wake Forest Baptist Comprehensive Cancer Center", "source_org_type": "医院", "row_number": 788, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "GHAA", "company": "The Chinese University of Hong Kong", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 33.5, "institution_score": 25, "track_score": 30, "milestone_score": 45, "field_heat_score": 40, "bonus_score": 0, "brief_reason": "GHAA为4味中药复方制剂（主要成分为穿心莲），机制可能涉及cathepsin抑制相关通路，但靶点未明确披露。大学机构研发，前临床阶段体内外抗转移活性较明确，但整体赛道非热门且机构非头部药企，总分较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/2873", "id": "9FXM_5wBX1NQZOEH-LO6", "source_drug_name": "GHAA", "title": "A novel 4-herb traditional Chinese medicine formula inhibits metastasis of triple-negative breast cancer", "abstract_text": "Background and Aim: Breast cancer is the most common cancer in women worldwide. Triple-negative breast cancer (TNBC) is the most aggressive breast cancer subtype with high metastatic capacity and dismal prognosis. Accumulating evidence suggests that Traditional Chinese Medicine (TCM) is a promising strategy for cancer treatment. Our team previously reported that a TCM formula consisting of H. diffusa, A. paniculata, A. senticosus, and C. sinensis exhibited a potent antitumor effect in a metastatic breast cancer mouse model. The formula was shown to reduce metastatic lesions in the lungs and livers of experimental mice. Recently, we modified this herbal formula by substituting C. sinensis with G. lucidum (a potent immunostimulatory herb) with an aim to improve the antitumor and antimetastatic efficacy. This study aimed to (i) investigate this modified formula (hereafter called GHAA) systematically both in vitro and in vivo, and (ii) elucidate its mechanism of action by bioinformatics analysis.\nMethod: Morphological and chemical authentications of the herbs were accomplished in accordance with the Chinese Pharmacopoeia. The anticancer effect of GHAA or its 4 individual herb extracts was evaluated in the TNBC cell line by MTT assay. The synergistic anticancer effect was analyzed by the SynergyFinder software. Anti-migration and -invasion effects were evaluated by wound healing and invasion assays, as well as in the zebrafish xenograft model. RNA sequencing was conducted in TNBC cells treated with GHAA or its individual herbs to elucidate the differentially expressed genes and altered pathways following treatment. The transcriptomic signatures induced by GHAA or its individual herbs were queried against the Connectivity Map database to elucidate their possible mechanism of action. The antitumor and anti-metastatic efficacy of GHAA was also investigated in nude mice bearing TNBC tumor xenografts in vivo.\nResults: GHAA inhibited TNBC proliferation in a concentration-dependent manner in vitro (IC50 ~ 1 mg/mL). Simultaneous combination of GHAA and doxorubicin was mildly synergistic. GHAA induced apoptosis, but it had no effect on cell cycle regulation. Also, GHAA was shown to significantly inhibit TNBC migration and invasion, and metastasis in the zebrafish model. RNA-seq analysis revealed that ribosomal biogenesis is the top altered biological process by GHAA. Using the connectivity mapping approach, the most potent herb (A. paniculata; IC50 ~ 0.2 mg/mL) within GHAA was found to share a highly similar transcriptomic signature as cathepsin inhibitors, implying its mechanism of action. Finally, GHAA also displayed significant antitumor and anti-metastatic efficacy in TNBC-inoculated nude mice without inducing notable toxicity.\nConclusion: The findings advocate clinical evaluation of GHAA for the treatment of metastatic TNBC.", "source_company": "The Chinese University of Hong Kong", "source_org_type": "大学", "row_number": 822, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "Galangin", "company": "Alexandria University", "org_type": "大学", "target": "TINCR", "modality": "other", "importance_level": "低", "total_score": 33.5, "institution_score": 25, "track_score": 45, "milestone_score": 30, "field_heat_score": 40, "bonus_score": 0, "brief_reason": "Galangin通过下调TINCR表达抑制肝癌干细胞增殖和干性特征，机制为天然小分子化合物调控lncRNA。机构为大学、非临床阶段、无显著开发亮点，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/684", "id": "cZ7M_5wBZznHJdnt_W3O", "source_drug_name": "Galangin", "title": "Galangin effectively inhibits the proliferation and stemness characteristics of liver cancer stem cells by knocking down the expression of TINCR.", "abstract_text": "Hepatocellular carcinoma (HCC) is a leading cause of cancer-related deaths worldwide. Liver cancer stem cells (LCSCs) are thought to play a crucial role in its pathology, but their mechanisms in HCC remain poorly understood. TINCR (terminal differentiation-induced long non-coding RNA) influences cancer cell behavior in various malignancies, including HCC. Recent research has highlighted the potential of natural anticancer agents, particularly Galangin (GLN). This compound is recognized for its antibacterial, antifungal, and antiviral properties, and it may also contribute to managing conditions like hypertension, diabetes, and cancer prevention. However, the specific effects of GLN on HCC are still not fully understood. The present study aims to explore the molecular mechanism and anticancer properties of GLN on TINCR expression, which may influence the stemness characteristics of liver cancer stem cells (LCSCs). Our findings demonstrate that TINCR is highly expressed in LCSCs, suggesting that it is essential for maintaining the stemness properties and tumorigenesis of these cells. In the Wst-1 assay, GLN treatment exhibited a dose-dependent inhibitory effect on proliferation and induced significant morphological changes in LCSCs, indicative of apoptosis induction after 24 h of treatment. Furthermore, the expression of TINCR was significantly inhibited after 24 h of GLN treatment compared to the control. Western blot analysis and qRT-PCR were conducted to assess oncogenic signaling pathways, including β-catenin, mTOR, and STAT3, along with downstream targets. Our results indicated a significant reduction in cell viability and oncogenic signals, as well as in LCSC stemness markers, following GLN treatment combined with TINCR knockdown, suggesting that inhibiting TINCR expression alongside GLN treatment effectively disrupts oncogenic signals and inhibits LCSC stemness characteristics. In addition, TINCR knockdown significantly enhanced the antiproliferative effects and sensitivity to Doxorubicin. Our data introduce GLN as a promising, natural, and non-toxic anticancer compound, demonstrating its therapeutic potential for treating HCC by regulating the expression pattern of TINCR.", "source_company": "Alexandria University", "source_org_type": "大学", "row_number": 1025, "target_meta": "TINCR", "MOA_meta": "其他"}, {"drug_name": "Periplocin", "company": "Nankai University", "org_type": "大学", "target": "HTR1E", "modality": "other", "importance_level": "低", "total_score": 33.5, "institution_score": 25, "track_score": 40, "milestone_score": 35, "field_heat_score": 40, "bonus_score": 3, "brief_reason": "Periplocin为从中药提取的天然小分子，通过竞争性结合释放CTCF以恢复HTR1E表达及其抗肿瘤信号，抑制卵巢癌增殖和腹膜转移。机构为大学非企业研发、处于preclinical机制研究阶段且HTR1E非热门靶点，导致整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8895", "id": "r57M_5wBZznHJdnt_W3O", "source_drug_name": "Periplocin", "title": "Periplocin restores HTR1E signaling by CTCF to inhibit proliferation and dissemination of ovarian cancer", "abstract_text": "Ovarian cancer (OC) is one of the three malignant tumors threatening women's health, ranking third in incidence and second in mortality among all the gynaecological malignancies. The high mortality of OC is due to the lack of typical symptoms and effective early screening methods in the early stage. In the rapid progression of ovarian cancer, a risk factor that cannot be ignored and is currently a hot topic of cancer research is psychological stress. It is largely unknown about the key and robust factors directly linking psychological stress to the dissemination of cancer cells, causing the lack of effective intervening method. The dysregulation of the neurotransmitter 5-Hydroxytryptamine (5-HT) and its receptor HTR1E-mediated dissemination-suppressing function played an essential role in the growth and peritoneal dissemination of OC, indicating HTR1E to be a potential target for the prevention of the malignant progression of OC. In a previous systematic study screening Periplocin as monomer molecule isolated from the traditional Chinese medicine, it can effectivly restore the HTR1E expression and its anti-tumor signaling against the malignant growth and peritoneal disseminated metastasis of OC. We next found CTCF as insulator enforces TAD boundary between HTR1E and ZNF292 in cancer. CTCF is released from the boundary through competitive binding by Periplocin. In summary, we the first time identified Periplocin to be an effective natural small molecule that was able to restore the HTR1E expression and its anti-tumor signaling against the malignant growth and peritoneal disseminated metastasis of OC. We also clarified the molecular mechanism of the anti-tumor effects of Periplocin. This provides new evidence for the clinical treatment of ovarian cancer.", "source_company": "Nankai University", "source_org_type": "大学", "row_number": 1071, "target_meta": "HTR1E", "MOA_meta": "其他"}, {"drug_name": "DPP8 inhibitor", "company": "Aga Khan University Hospital", "org_type": "医院", "target": "DPP8", "modality": "inhibitor", "importance_level": "低", "total_score": 33.5, "institution_score": 25, "track_score": 45, "milestone_score": 30, "field_heat_score": 40, "bonus_score": 0, "brief_reason": "靶向DPP8的小分子抑制剂，通过诱导线粒体介导的凋亡途径在胶质母细胞瘤和结直肠癌细胞中显示作用。机构为医院/大学类型且仅体外研究，赛道非热门且无明确临床里程碑，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6082", "id": "lZ7M_5wBZznHJdnt_W7P", "source_drug_name": "DPP8 inhibitor", "title": "Advancing cancer treatment through targeting dipeptidyl peptidase 8 an innovative strategy for overcoming resistance", "abstract_text": "Cancer remains one of the most complex and challenging diseases because of its heterogeneity and the ability of tumor cells to become resistant to the treatment. Among various cancers, glioblastoma and colon cancers are the most prevalent and deadliest cancer worldwide. It is responsible for significant burden on the healthcare system and affects millions of lives every year. Despite advancement in cancer treatment, including chemotherapy, radiotherapy, targeted therapies, and immunotherapy, achieving complete remission remains challenging that contributes to the poor prognosis of glioblastoma patients. One promising area of research involves a group of enzymes called dipeptidyl peptidases DPPs, a family of serine proteases which are known to regulate various biological processes, including immune function, metabolism, and cancer progression. Dipeptidyl peptidases DPPs, particularly DPP8, have emerged as promising molecular targets in cancer therapy. This study investigates the mechanistic role of DPP8 inhibition in glioblastoma and colorectal cancer cells. Cell viability was assessed using trypan blue and CCK8 assays, while apoptosis was evaluated via Giemsa staining, DNA fragmentation, Annexin V FITC PI, and cell cycle analysis. Flow cytometry revealed increased ROS production, loss of mitochondrial membrane potential and intracellular calcium level following treatment. Western blotting showed enhanced expression of apoptosis-related proteins 24 hr after treatment with DPP8 inhibitor. These findings suggest that DPP8 inhibition induce mitochondria mediated apoptotic pathways and may serve as a novel therapeutic strategy, offering potential for targeted and personalized cancer treatment approaches.", "source_company": "Aga Khan University Hospital", "source_org_type": "医院", "row_number": 1226, "target_meta": "DPP8", "MOA_meta": "抑制剂"}, {"drug_name": "anti-PD-1", "company": "Barbara Ann Karmanos Cancer Institute", "org_type": "研究机构", "target": "未披露", "modality": "inhibitor", "importance_level": "低", "total_score": 33, "institution_score": 20, "track_score": 70, "milestone_score": 10, "field_heat_score": 40, "bonus_score": 0, "brief_reason": "药品为anti-PD-1（免疫检查点抑制剂），但摘要被embargo，未披露任何具体药物靶点或新机制细节，仅为研究机构基础研究。机构非头部药企导致低分，开发阶段为preclinical且信息极少，赛道虽涉及热门PD-1但无新亮点。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11386", "id": "6FXM_5wBX1NQZOEH-LO6", "source_drug_name": "anti-PD-1", "title": "Targeting XPO1 reprograms immune microenvironment and confers sensitivity to immune checkpoint blockade in pancreatic ductal adenocarcinoma", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Barbara Ann Karmanos Cancer Institute", "source_org_type": "研究机构", "row_number": 63, "target_meta": "not available", "MOA_meta": "抑制剂"}, {"drug_name": "SYTO RNASelect Red", "company": "University of Oregon", "org_type": "大学", "target": "未披露", "modality": "荧光显像剂", "importance_level": "低", "total_score": 33, "institution_score": 25, "track_score": 40, "milestone_score": 35, "field_heat_score": 45, "bonus_score": 0, "brief_reason": "SYTO RNASelect Red 为Thermo Fisher Scientific开发的新型RNA选择性荧光染料，主要用于核仁应激的显像与高通量筛选，非治疗性药物。大学机构+工具类试剂+早期方法学开发导致整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6492", "id": "eVXM_5wBX1NQZOEH-LK6", "source_drug_name": "SYTO RNASelect Red", "title": "Deep learning-driven image analysis for tracking nucleolar morphology", "abstract_text": "Introduction: The nucleolus, a membraneless nuclear organelle responsible for ribosome production, is highly sensitive to stress. A subset of chemotherapeutic drugs induce nucleolar stress, which could influence their apoptotic mechanisms. However, tracking morphological changes of the nucleolus during treatment remains challenging due to its amorphic state and nanoscale organization. A major bottleneck for drug screening and mechanistic studies is the reliance on time-intensive manual imaging and immunostaining to identify nucleolar stress. To overcome this we have developed a suite of image analysis models to rapidly identify and classify cells.\nMethods: The mechanisms that lead to nucleolar stress by small molecules and mechanisms that allow the nucleolus to recover from reversible stress remain unclear. To facilitate time-dependent morphological studies as well as general drug screening for nucleolar defects, we developed deep learning models leveraging Thermo Fisher Scientific’s RNA-selective dyes to automatically detect and quantify nucleolar stress from microscopy images. Using osteosarcoma cells, we successfully classified stressed and unstressed populations with SYTOTM RNASelectTM Red, a novel RNA-selective dye developed by Thermo Fisher Scientific. This dye can be implemented into rapid high-throughput imaging methods for cancer detection and drug screening. Using these deep-learning models we can rapidly screen for novel chemotherapeutics and study the efficacy of current nucleolar stress-causing drugs.\nResults: Osteosarcoma cells labeled with SYTOTM RNASelectTM Red and treated with chemotherapeutics display distinct nucleolar staining enabling precise segmentation and quantitative analysis. Under chemotherapeutic treatment nucleoli decrease in size and become more rounded. Our deep learning models not only identify which cells are experiencing nucleolar stress but also determine the specific stage of stress for each cell. These results have been validated through current known methods to identify nucleolar stress such as immunocytochemistry and RNA production assays. This platform now allows us to investigate how cells recover from reversible nucleolar stress, providing a high-throughput approach to dissect nucleolar function, resilience, and responses to chemotherapeutic treatment.\nConclusions: SYTOTM RNASelectTM Red is an effective RNA dye because it provides a bright stain for the nucleolus, enabling clear segmentation and quantitative analysis using machine learning. Its compatibility with immunocytochemistry allows for high-resolution, dynamic studies of RNA biology and cellular stress responses, making it a versatile tool for both single cell and population-level investigations. This dye, coupled with our deep-learning methods, opens the door to broad screening protocols, allowing for a spectrum of drug candidates to be tested rapidly.", "source_company": "University of Oregon", "source_org_type": "大学", "row_number": 1273, "target_meta": "not available", "MOA_meta": "荧光显像剂"}, {"drug_name": "NMD inhibitor", "company": "University of Wisconsin-Madison", "org_type": "大学", "target": "未披露", "modality": "inhibitor", "importance_level": "低", "total_score": 32.5, "institution_score": 25, "track_score": 45, "milestone_score": 30, "field_heat_score": 40, "bonus_score": 0, "brief_reason": "NMD抑制剂针对EBV裂解诱导的机制研究，靶点未明确披露，仅为工具化合物探索阶段。机构为大学、尚处基础机制研究、无临床里程碑，整体开发重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1483", "id": "FlXM_5wBX1NQZOEH-LG5", "source_drug_name": "NMD inhibitor", "title": "Investigating nonsense-mediated decay (NMD) as a restriction factor for EBV-reactivation", "abstract_text": "Approximately 0.01% of adults infected with Epstein-Barr virus (EBV) will develop an EBV-associated cancer which equates to 200,000 annual cases globally. EBV malignancies are dependent on EBV latency gene products for continued growth and survival, making the disruption of latency a promising therapeutic approach. Despite this vulnerability, EBV-targeting strategies have yet to be successfully translated into therapy for EBV-associated cancers. “Lytic induction therapy” combines small molecules capable of reactivating EBV from latency with antiviral drugs to increase toxicity to tumor cells and prevent EBV particle production. Although this therapeutic strategy has been well tolerated in clinical trials, current induction agents display low efficacy. The full potential of this approach will require the development of second-generation induction agents, necessitating a greater understanding of EBV biology and host-pathogen interactions. Recent studies have identified nonsense-mediated decay (NMD), a host regulatory pathway, is a key restriction factor for EBV reactivation. The EBV transcript encoding Rta, one of the two viral transcription factors responsible for entry into the lytic cycle, contains multiple splice junctions downstream of its stop codon. Consequently, the Rta transcript is rapidly degraded by NMD. This previously unrecognized post-transcriptional regulation revealed that strategies inducing the lytic cycle cannot focus solely on activating Rta and Zta transcription; they must include approaches to stabilize the Rta transcript, likely by NMD inhibition. To investigate this phenomenon, we developed an NMD reporter based on a previously described dual-fluorophore system. By combining this reporter with an EBV fluorescent reporter virus that indicates Zta (red) and Rta (green) promoter activity, we can assess the effects of NMD on Rta expression and lytic activation (measured as the change in blue and far-red fluorescence). This system enables us to determine whether EBV can only reactivate under NMD-low conditions and evaluate how various induction agents influence NMD activity. We can also identify EBV gene products that may act as NMD antagonists, which would establish a positive feedback loop for promoting lytic cycle entry. The insights gained from these studies will provide a deeper understanding of the mechanisms governing viral reactivation and inform the development of next generation lytic induction therapies.", "source_company": "University of Wisconsin-Madison", "source_org_type": "大学", "row_number": 7, "target_meta": "not available", "MOA_meta": "抑制剂"}, {"drug_name": "cyanidin-3-O-glucoside", "company": "The Angiogenesis Foundation", "org_type": "公益机构", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 32.5, "institution_score": 25, "track_score": 40, "milestone_score": 30, "field_heat_score": 45, "bonus_score": 0, "brief_reason": "cyanidin-3-O-glucoside为蓝莓中天然花青素成分，主要涉及饮食干预的血管生成抑制机制，但靶点未明确披露。机构为公益组织、非商业研发，处于基础营养研究阶段，无药物开发里程碑，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6711", "id": "DlXM_5wBX1NQZOEH-LS6", "source_drug_name": "cyanidin-3-O-glucoside", "title": "Variability in anthocyanin content among commercial blueberries and implications for dietary cancer prevention", "abstract_text": "Early intervention through dietary cancer prevention may reduce tumor risk, as supported by experimental models and epidemiologic studies linking diet to lower cancer incidence. Mechanisms of cancer prevention for many edible fruits are mediated by bioactive phytonutrients. For example, consumption of two servings of blueberries per week was associated with a 25% lower cancer mortality among breast cancer patients in the Nurses' Health Study, and anthocyanin consumption was linked to a 22% reduced risk of colorectal cancer in a meta-analysis. Anthocyanins, a major class of bioactive flavonoids in blueberries, modulate endothelial growth and inhibit VEGF-driven angiogenesis in preclinical models, suggesting that differences in anthocyanin concentration across blueberry cultivars may influence their anticancer potential. Commercially grown blueberries are available in a variety of cultivars and regions, potentially resulting in substantial variability in anthocyanin content and bioactivity. To investigate this and identify candidates for mechanistic studies, blueberries were collected from 11 commercially available sources. Samples were frozen at -20°C, pulverized, solvent-extracted, and analyzed by high-performance liquid chromatography (HPLC) in triplicate, using cyanidin-3-0-glucoside (C3G) as a validated standard. Anthocyanin concentrations ranged from 0.204 to 4.244mg/g wet weight (C3G equivalents). Wild lowbush Maine blueberries contained the highest anthocyanin concentrations and had a distinct chromatographic profile, while highbush cultivars, which dominate U.S. commercial blueberry production, showed more variable levels, with several also ranking relatively high. Overall, these findings demonstrate that anthocyanin content differs significantly among blueberry types and provide a rationale for selecting specific cultivars for mechanistic studies of dietary angioprevention. Based on these results, representative extracts (high and low anthocyanin content) were selected for subsequent in vitro studies of endothelial tube formation. Such comparative biochemical characterization is essential to optimize the design of future investigations into the cancer-preventive potential of blueberry-derived anthocyanins.", "source_company": "The Angiogenesis Foundation", "source_org_type": "公益机构", "row_number": 69, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "ANC", "company": "Aix-Marseille University", "org_type": "大学", "target": "HER2", "modality": "other", "importance_level": "低", "total_score": 32.5, "institution_score": 25, "track_score": 45, "milestone_score": 30, "field_heat_score": 40, "bonus_score": 0, "brief_reason": "ANC为曲妥珠单抗功能化的纳米颗粒递送多西他赛，主要靶向HER2阳性乳腺癌模型。大学机构前期纳米递送研究，免疫调控效应微弱且趋势性，未达临床阶段，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9479", "id": "81XM_5wBX1NQZOEH-LK6", "source_drug_name": "ANC", "title": "Quantitative and functional immune reprogramming induced by a nanomedicine in breast cancer model", "abstract_text": "Nanoparticles (NPs) are emerging as a promising strategy in oncology, offering optimised drug delivery and the potential to modulate immune responses. In this study, we developed an innovative nanoparticle encapsulating docetaxel and functionalised with trastuzumab for precise targeting of HER2-positive tumours (called ANC for Antibody Nanoparticle Conjugate). Immunomodulatory effects were performed in C57BL/6 mice administered free docetaxel (1.6 mg-kg-¹) and trastuzumab (135 ng-kg-¹) by intraperitoneal injection (n = 29) or ANC (nanoparticles at the same docetaxel and trastuzumab doses as the free drugs, n = 40). Immune profiling was performed in blood (J0-J21) and tumor tissue (J21) to evaluate quantitative and functional changes in major lymphoid and myeloid subsets involved in antitumor immunity. Flow cytometric analyses included B cells, T cells (CD4⁺, CD8⁺), activated T-cell subsets, NK cells, regulatory T cells (Treg), myeloid-derived suppressor cells (MDSC), and regulatory B cells (Breg). In blood, no significant differences were observed between groups for B cells, NK cells, CD4⁺ or CD8⁺ T cells, or their activated subsets. A trend toward reduced Treg frequencies was detected in the ANC group compared with controls (p = 0.053), suggesting early systemic modulation of immunosuppressive activity. MDSC levels remained unchanged across all groups. In tumors, global B-cell levels were comparable between groups, but ANC-treated mice showed an increased proportion of Breg, indicating a potential local immunosuppression. NK-cell infiltration and activation tended to be higher in the ANC group (p ≈ 0.08), suggesting localized immune stimulation. No differences were detected for CD4⁺ T cells, whereas a reduction in CD8⁺ T-cell frequency was observed in ANC-treated tumors. Treg levels also showed a decreasing trend (p = 0.07), consistent with a partial reduction in immunoregulatory pressure within the tumor microenvironment. MDSC levels did not differ significantly between conditions. ANC formulation exhibited subtle yet biologically relevant immunomodulatory trends, including reduced Treg frequencies and increased activated NK cells within the tumor, potentially favoring antitumor responses. Conversely, the elevated Breg population in ANC-treated tumors may counterbalance these effects by promoting local immunosuppression. These findings suggest that ANC may fine-tune the tumor immune landscape without inducing major systemic alterations. Further investigation with extended cohorts and functional assays will be required to confirm these trends and clarify their implications for therapeutic efficacy.", "source_company": "Aix-Marseille University", "source_org_type": "大学", "row_number": 226, "target_meta": "HER2", "MOA_meta": "其他"}, {"drug_name": "SK6", "company": "St Mary's College of Pharmacy", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 32.5, "institution_score": 25, "track_score": 35, "milestone_score": 35, "field_heat_score": 40, "bonus_score": 0, "brief_reason": "SK6为新型苯并吡喃衍生物，靶点机制未明确披露，仅显示体外MCF-7细胞S期阻滞和轻度凋亡诱导。大学机构早期preclinical研究，赛道非热门modality且无明确靶点，整体开发价值和关注度较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3463", "id": "UVXM_5wBX1NQZOEH-LG5", "source_drug_name": "SK6", "title": "Flow-cytometric analysis of cell-cycle arrest and apoptosis induced by a novel benzopyran derivative (SK6) in MCF-7 breast cancer cells", "abstract_text": "Introduction: Breast cancer remains a major global health challenge, accounting for 2.3 million new cases and nearly 670,000 deaths in 2022. The limitations of current therapies, including drug resistance, toxicity, and reduced efficacy, highlight the urgent need for novel anticancer agents.\nPurpose of the Study: The aim of this study was to evaluate the anticancer potential of a novel benzopyran derivative (SK6) using flow-cytometric analysis. After identifying SK6 as the most potent compound through MTT assay, its mechanism of action was investigated in MCF-7 cells. Flow cytometry was employed to assess SK6-induced apoptosis using Annexin-V/PI staining. Additionally, PI-based DNA content analysis was performed to determine the compound’s effect on cell-cycle progression.\nExperimental Methods: In continuation our research on synthesis of benzopyran derivatives, 5 molecules were synthesized and characterized using UV, IR, ¹HNMR, and mass spectrometry. Their cytotoxicity was evaluated against MCF-7 cells using the MTT assay. Consequently, SK6 was selected for mechanistic investigation. Flow cytometry (Beckman Coulter Gallios analyser, USA) was employed to assess its effects on the cell cycle and apoptosis in treated MCF-7 cells.\nResults: All five benzopyran derivatives were successfully synthesized and structurally confirmed using spectral analyses. Among them, SK6 showed the lowest IC₅₀ value i.e. 20.99μg/ml in the MTT assay, demonstrating the strongest antiproliferative activity against MCF-7 cells. Flow-cytometric Annexin-V FITC/PI analysis revealed that SK6 treatment induced a measurable apoptotic response in MCF-7 cells. Annexin-V FITC/PI staining revealed that SK6 induced a measurable apoptotic response. Quadrant analysis showed 78.44% viable cells, 8.40% in early apoptosis, 8.15% in late apoptosis, and 5.01% necrotic. Overall, SK6 induced 16.55% total apoptosis, confirming its ability to activate programmed cell death in MCF-7 cells. The SK6 compound caused a marked alteration in the cell-cycle profile, producing a dominant S-phase arrest. Treated cells showed a substantial increase in the S-phase population (54.33% vs. 13.05% in control) with a drastic reduction in G0/G1 cells (1.02% vs. 62.91%). A moderate rise in G2/M cells and minimal sub-G1 events indicate primarily cytostatic rather than DNA-fragmenting effects. These findings suggest that SK6 disrupts DNA replication and halts progression at the S-phase checkpoint.\nConclusion: SK6 demonstrated potent cytotoxic activity against MCF-7 cells and caused a pronounced S-phase arrest, indicating disruption of DNA replication. This was accompanied by a moderate induction of apoptosis, supporting its antiproliferative effect. Finally, these results highlight SK6 as a promising lead candidate for further development as a selective and effective therapeutic agent against breast cancer", "source_company": "St Mary's College of Pharmacy", "source_org_type": "大学", "row_number": 366, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "PQ", "company": "Texas Tech University", "org_type": "大学", "target": "未披露", "modality": "gap junction enhancer", "importance_level": "低", "total_score": 32.5, "institution_score": 25, "track_score": 40, "milestone_score": 35, "field_heat_score": 40, "bonus_score": 0, "brief_reason": "PQ为gap junction enhancer，通过恢复间隙连接功能在体外模型中与化疗药如doxorubicin显示浓度依赖性协同作用，但靶点未明确披露。大学机构、非热门modality、仅preclinical体外协同数据导致总体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6555", "id": "WFXM_5wBX1NQZOEH-LK6", "source_drug_name": "PQ", "title": "Synergistic effects of antineoplastic drugs and gap junction enhancer in heterogenous colorectal cancer", "abstract_text": "Fibroblast tumor cell crosstalk, particularly through gap junction mediated signaling, is increasingly recognized as a modifier of colorectal cancer drug response. To test whether restoring gap junction function can enhance chemotherapy, we used co-culture spheroids composed of CCD-112 CoN fibroblasts and colorectal cancer cells (SW620, SW480, HT-29, or Caco-2) in a 1:1 ratio in 96-well plates. Doxorubicin, erlotinib, nilotinib, and cediranib were tested across multiple concentrations, alone and in combination with the gap junction enhancer, PQ, and drug interactions were quantified using the ZIP model, analytic tool and visualized using gigamap approach. For the combination treatment of doxorubicin and PQ, ZIP analysis revealed both antagonistic and synergistic regions. PQ alone and low concentrations of doxorubicin were predominantly antagonistic, with ZIP scores ranging from approximately 0.2 to −17.19. In contrast, high concentrations of both chemicals produced marked synergy, with a maximal ZIP score of 44.05 and an overall global ZIP synergy score of 4.53. On the 2D heatmap, this appears as largely additive to mild antagonistic effects at low to intermediate doses, with a distinct red hot spot of synergy in the upper-right corner (high [PQ]/high [Doxorubicin]). Consistently, the 3D surface plot shows a ridge of positive zip scores that increases with rising concentrations of both drugs. Together, these findings indicate that PQ enhances doxorubicin efficacy in a concentration dependent manner, with synergy restricted to a specific high-dose window rather than across all dose combinations. Similarly, the BCR-ABL targeted therapy nilotinib displayed a biphasic response in combination with PQ, characterized by two synergistic peaks at low and high concentrations separated by an antagonistic valley at intermediate doses. In conclusion, these results highlight both the synergistic and antagonistic properties of PQ with commonly used antineoplastic agents and support the approach of combinational treatment for colorectal cancer.", "source_company": "Texas Tech University", "source_org_type": "大学", "row_number": 542, "target_meta": "not available", "MOA_meta": "强化剂"}, {"drug_name": "SU-CCS-1 lipid extract-modified nanoliposomes", "company": "Massachusetts College of Pharmacy & Health Sciences", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 32.5, "institution_score": 25, "track_score": 45, "milestone_score": 30, "field_heat_score": 40, "bonus_score": 0, "brief_reason": "该纳米脂质体利用SU-CCS-1细胞脂质提取物增强对透明细胞肉瘤模型细胞的靶向摄取，但未披露具体药物或靶点，处于早期体外优化阶段。大学机构、非热门modality、缺乏明确里程碑导致整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5571", "id": "mJ7M_5wBZznHJdnt_W3O", "source_drug_name": "SU-CCS-1 lipid extract-modified nanoliposomes", "title": "SU-CCS-1 lipid extract-modified nanoliposomes and characteristic growth profile of a model clear cell sarcoma target cell line", "abstract_text": "Background: Sarcomas account for approximately 1% of adult cancers and 15% of childhood cancers in the United States. Conventional treatment strategies are somewhat effective during early disease, but once metastasized, treatment success significantly declines. Nanomedicine presents an alternative approach to increase current treatment efficacy and prolong survival. Optimization of liposomal preparations is essential to ensure the most selective targeting. The objective of the study was to develop a novel nanoliposomal drug delivery system using a cellular model of human clear cell sarcoma in vitro.\nMethods: The SU-CCS-1 cell line was selected as the cellular model for clear cell sarcoma and used for the drug selectivity studies. SU-CCS-1 cells were cultured and expanded in vitro for cellular extraction purposes. Cellular lipid extract (LE) material was derived from a clear cell sarcoma target (SU-CCS-1) cell line. Nanoliposomes were optimized for LE and cholesterol content. DPPE-Rhodamine (used as a fluorescence indicator) for cellular uptake studies, and a fluorescence microplate reader was used to assess relative fluorescence intensity values. Phase I of evaluation included characterization of cells and cellular uptake properties of nanoliposomal preparations of DOPC and cholesterol consisting of 0, 5, and 10 mol% cholesterol content. To characterize the cellular growth characteristics, separate flasks were prepared with either 100% adherent or 100% suspension cells acquired from a mature mixed cell population. The percentage of adherent and suspension cells was determined on Day 0 and Day 5.\nResults: An evaluation of growth profile characteristics of the SU-CCS-1 target cell line revealed a substantial transformation of suspension cells to adherent cells over time. While the flask of 100% adherent cells remained 72% adherent after 5 days, the flask of 100% suspension cells transformed to become 59% adherent after 5 days. The particle size for nanoliposomes containing 0, 5, and 10 mol% cholesterol was 283 nm, 139.9 nm, and 247 nm, respectively. Additionally, the inclusion of 10 mol% SU-CCS-1-LE increased uptake of nanoliposomes compared to 0% LE control preparations (without SU-CCS-1-LE).\nConclusion: Preliminary findings suggest that the DOPC:cholesterol ratio affects nanoliposome uptake by SU-CCS-1 cells. The inclusion of SU-CCS-1-LE in nanoliposomes enhances their targeting efficiency. Ongoing studies will investigate the effect of dual incorporation of optimized cholesterol and SU-CCS-1-LE content on the targeting of clear cell sarcoma.", "source_company": "Massachusetts College of Pharmacy & Health Sciences", "source_org_type": "大学", "row_number": 1053, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "27-hydroxycholesterol", "company": "Molecular and intergrative physiology", "org_type": "学术研究机构", "target": "LXR", "modality": "other", "importance_level": "低", "total_score": 32, "institution_score": 20, "track_score": 60, "milestone_score": 20, "field_heat_score": 50, "bonus_score": 0, "brief_reason": "27-hydroxycholesterol为天然LXR配体（内源性激动剂），摘要中用于多组学研究揭示LXR在髓系免疫细胞中的选择性调控机制，而非作为药物候选物开发；机构为学术部门，无公司背景，处于基础研究早期，无明确药物开发里程碑。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/1926", "id": "llXM_5wBX1NQZOEH-LG6", "source_drug_name": "27-hydroxycholesterol", "title": "Multiomic profiling reveals ligand and cell specific regulatory programs of LXR selective modulation in myeloid immune cells", "abstract_text": "Selective modulation of steroid nuclear receptors such as estrogen (ER), glucocorticoid (GR), and androgen receptors (AR) has advanced cancer therapy by enabling precise control of receptor signaling. However, selective modulation of other nuclear receptors remains underexplored. Liver X receptors (LXRs) are key regulators of cholesterol homeostasis, inflammation, and immune responses. LXR ligands have shown antiproliferative and immunomodulatory effects across multiple cancers, including prostate, breast, and colorectal cancers, as well as hematologic tumors. Certain LXR ligands also attenuate immunosuppressive cell populations in the tumor microenvironment, making LXR a promising therapeutic target.\nHowever, many synthetic LXR agonists have shown adverse metabolic and neurologic effects and their impact on tumor progression is often inconsistent, suggesting potential ligand- and cell-specific modulation. Understanding the mechanisms underlying such selective LXR modulation, inspired by established selective modulation strategies for ER and AR related cancers, may enable the development of safer and more effective LXR-directed cancer therapies.To elucidate the mechanism of selective LXR modulation in myeloid cells, we performed multi-omics profiling (RNA-seq, ATAC-seq, and RIME proteomics) on murine bone marrow derived macrophages and dendritic cells treated with seven LXR ligands. We observed both shared and ligand- or cell-specific transcriptional and chromatin accessibility patterns. Notably, 27-hydroxycholesterol (27HC) suppressed interferon/STAT1 programs in macrophages and induced a MYC/E2F associated immunosuppressive state, whereas dendritic cells exhibited suppression of interferon stimulated genes and MYC/E2F program.T cell proliferation can be suppressed by 27HC treated macrophages. Preliminary functional assays suggested that this effect could be reversed by inhibiting E2F pathway (CDK4/6 blockade) or by targeting NF-κB, STAT3, or HDAC2 signaling in macrophages. These findings delineate cell-specific mechanisms of LXR selective modulation and suggest that targeting LXR may fine-tune E2F, NF-κB, STAT3, and HDAC2 dependent signaling that impacting macrophage-T cell crosstalk and thereby enhance T cell antitumor function.", "source_company": "Molecular and intergrative physiology", "source_org_type": "未知", "row_number": 412, "target_meta": "LXR", "MOA_meta": "其他"}, {"drug_name": "proscillaridin A", "company": "Aspiring Scholars Directed Research Program", "org_type": "研究机构", "target": "未披露", "modality": "inhibitor", "importance_level": "低", "total_score": 31.5, "institution_score": 20, "track_score": 40, "milestone_score": 45, "field_heat_score": 30, "bonus_score": 0, "brief_reason": "proscillaridin A 为天然心脏苷类化合物，主要通过Na+/K+-ATPase抑制等机制发挥抗癌作用，但摘要中未明确披露具体靶点，仅报道了糖基修饰类似物的体外和体内抗实体瘤活性。机构为高中生科研项目，非专业药企，赛道为经典天然产物衍生物而非热门前沿modality，处于早期preclinical阶段且有ADMET限制，故整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/2867", "id": "sVXM_5wBX1NQZOEH-LK6", "source_drug_name": "proscillaridin A", "title": "Preclinical discovery of proscillaridin A glycan analogs for the in vitro and in vivo treatment of solid tumors", "abstract_text": "Cancer persists as one of the leading causes of mortality in the US, accounting for over 2 million new cases and 611,000 deaths in 2024. In parallel, several small-molecule drugs are currently in development for the treatment of malignancies. Within those, natural products, their synthetic analogs, or other derivatives, account for about 50% of all FDA-approved anticancer small molecules. Several naturally-derived cardiac glycosides, including digoxin, digitoxin, and proscillaridin A, have been originally identified as cardiomyocyte modulators and are currently being investigated for their anti-cancer properties. These cardiac glycosides are generally classified into cardenolides and bufadienolides, which bear butenolide and pyrone D-ring functionality, respectively, and have exhibited remarkable in vitro toxicity in various cancerous cell lines. As simple modifications on steroidal small molecules have demonstrated success in augmenting bioavailability or enhancing downstream biological activities, we sought to prepare synthetic analogs of proscillaridin A, a bufadienolide isolated from the genus Scilla. We synthesized five analogs of proscillaridin A bearing acetate esters, silyl ethers, or dimethyl ketals to investigate how ketalization, acetylation, and/or silylation of the A-ring allylic glycoside might alter its anti-cancer properties. The antiproliferative activity of these compounds was evaluated alongside proscillaridin A and two model cardiac glycosides — digoxin and digitoxin — across several breast, colorectal, liver, and ovarian cancer cell lines. Through a diverse panel of cell viability and cytotoxicity experiments, reporter assays, and cell cycle and protein marker analysis by flow cytometry, we find that ketalization of the glycan of proscillaridin A provides similar, and in some cases enhanced, in vitro potency. Subsequently, to evaluate the preclinical applicability of these compounds in inhibiting solid tumor growth, we found that direct, intraperitoneal injection of proscillaridin A and its analogs demonstrated reasonably potent antitumor activity in a murine mammary cancer model, albeit with dose-limiting ADMET properties. This study establishes the foundation for further in vitro and in vivo evaluations of cardiac glycosides for the treatment of cancer.", "source_company": "Aspiring Scholars Directed Research Program", "source_org_type": "研究机构", "row_number": 173, "target_meta": "not available", "MOA_meta": "抑制剂"}, {"drug_name": "BCI", "company": "None (research compound)", "org_type": "university", "target": "DUSP6 (also DUSP1)", "modality": "small molecule inhibitor", "importance_level": "低", "total_score": 31, "institution_score": 40, "track_score": 30, "milestone_score": 10, "field_heat_score": 50, "bonus_score": 0, "brief_reason": "BCI is a preclinical research tool compound (small molecule allosteric inhibitor of DUSP6/DUSP1) used in academic in vitro studies on anoxic metastatic melanoma cells to resensitize to BRAFi like Dabrafenib by restoring pERK; from Midwestern University poster at AACR, no company involvement, no in vivo/clinical data, early exploratory stage with limited track record or milestones in drug development.", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6033", "id": "KlXM_5wBX1NQZOEH-LO6", "source_drug_name": "BCI", "title": "Resensitizing therapy-resistant anoxic metastatic melanoma cells", "abstract_text": "Introduction: Metastatic melanoma significantly reduces patient survival. Metastatic growth can outpace vascularization creating areas of extreme hypoxia or anoxia. HIF-1α is a master transcriptional regulator of cellular survival response to hypoxia that can facilitate the selection of more stem cell-like, drug-resistant cancer cells. BRAF inhibitors (BRAFi), commonly used to treat melanoma, targets cell signaling involving pERK-dependent melanoma growth. Resistance to BRAFi can lead to melanoma recurrence and poor survival. Dual specificity phosphatases (DUSP), such as DUSP6 can reduce ERK activity; moreover, DUSP6 has been shown to be upregulated by HIF-1α during cellular responses to hypoxia. We hypothesize that HIF-1α levels increase in metastatic melanoma cells as these adapt to the anoxic metastatic niche, which then increases DUSP6 expression, which in turn reduces ERK activity that causes resistance to BRAFi.\nMethods: Western blot (WB) was used to compare the expression of HIF-1α, pERK, and DUSP6 in lysates from A375 melanoma cells grown in anoxia or normoxia. An MTT cell proliferation, and a cell apoptosis assay were used to compare the effect of the BRAFi, Dabrafenib between treated normoxic and anoxic A375 cells. Lysates were collected for WB to assess effects on pERK between anoxic A375 treated with the DUSP6 inhibitor, BCI, and untreated control. Finally, to see if BCI can increase drug sensitivity, MTT and cell apoptosis assays were performed on anoxic A375 treated with both BCI and Dabrafenib.\nResults: WB results show that anoxic A375 cells express higher levels of HIF-1α, and lower levels of pERK compared to normoxic control cells. Dabrafenib treatment reduced cell proliferation of normoxic but not anoxic A375 cells, presumably due to reduced expression of the pERK target in these cells. Inhibition of DUSP6 with BCI significantly increased pERK expression and when combined with Dabrafenib significantly reduced proliferation and increased cell death of the anoxic A375 cells.\nConclusion: We show that melanoma cells cultured in anoxia express higher levels of HIF-1α. This in turn led to an increase in DUSP6 expression. In these anoxic cells, DUSP6, in turn, reduces pERK level, which is an important component of the signaling cascade targeted by Dabrafenib. Finally, our results from the combination treatment with both BCI and Dabrafenib suggest that by inhibiting DUSP6 it may be possible to re-express pERK in drug-resistant anoxic metastatic melanoma cells and reestablish drug sensitivity.", "source_company": "Midwestern Univ.\nMidwestern Univ. - Downers Grove Campus", "source_org_type": "大学", "row_number": 680, "target_meta": "DUSP6,DUSP1", "MOA_meta": "其他"}, {"drug_name": "GLP-1 receptor agonists", "company": "University of North Carolina at Chapel Hill", "org_type": "大学", "target": "GLP-1 receptor", "modality": "other", "importance_level": "低", "total_score": 31, "institution_score": 25, "track_score": 45, "milestone_score": 20, "field_heat_score": 40, "bonus_score": 0, "brief_reason": "GLP-1受体激动剂为已成熟的糖尿病/减重药物类别，靶点GLP-1R在肿瘤领域为非主流探索方向。大学机构preclinical机制研究无明确里程碑进展，整体在AACR语境下关注度与重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/526", "id": "flXM_5wBX1NQZOEH-LO6", "source_drug_name": "GLP-1 receptor agonists", "title": "Preclinical evidence for the anticancer effects and mechanisms of GLP-1 receptor agonists", "abstract_text": "There is no abstract associated with this presentation.", "source_company": "University of North Carolina at Chapel Hill", "source_org_type": "大学", "row_number": 735, "target_meta": "GLP-1R", "MOA_meta": "其他"}, {"drug_name": "fluorinated cuban-1-yl biguanides", "company": "University of Minnesota", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 31, "institution_score": 30, "track_score": 40, "milestone_score": 20, "field_heat_score": 30, "bonus_score": 0, "brief_reason": "药物为氟化cuban-1-yl biguanides类化合物，摘要被embargo未披露具体靶点和机制，推测可能抑制CYP3A4相关通路克服内分泌耐药。大学机构preclinical阶段，无显著里程碑，赛道非热门modality，总分较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11446", "id": "AFXM_5wBX1NQZOEH-LS6", "source_drug_name": "fluorinated cuban-1-yl biguanides", "title": "Fluorinated cuban-1-yl biguanides overcome hormone therapy resistance to standard of care fulvestrant, and palbociclib", "abstract_text": "Abstract is embargoed at this time.", "source_company": "University of Minnesota", "source_org_type": "大学", "row_number": 829, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "piR-60643", "company": "Loma Linda VA Medical Center", "org_type": "医院", "target": "FABP5", "modality": "other", "importance_level": "低", "total_score": 30.8, "institution_score": 25, "track_score": 45, "milestone_score": 20, "field_heat_score": 35, "bonus_score": 3, "brief_reason": "piR-60643为靶向FABP5的piRNA模拟物，通过下调FABP5抑制肺癌细胞脂代谢和增殖，机制新颖但仅为体外preclinical研究。机构为医院/VA医疗中心、modality非主流热门、开发阶段早期导致总体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/2354", "id": "PlXM_5wBX1NQZOEH-LK6", "source_drug_name": "piR-60643", "title": "PiR-60643 is a novel inhibitor of fatty acid binding protein 5 (FABP5) in lung cancer cells", "abstract_text": "Introduction: It is important to discover and characterize new pathways and their associated gene networks in cancer cells to develop effective diagnostic and therapeutic tools. Our laboratory is focused on the impact of the RASSF1C-PIWIL1-piRNA pathway on non-small cell lung cancer (NSCLC) cell growth; and our studies have resulted in identifying specific PIWI-interacting RNAs (piRNAs) that appear to function both as oncogenes and tumor suppressors. Among the recent piRNAs identified, we found that piR-60643 targets fatty acid bind protein 5 (FABP5) in lung cancer and appears to function as a tumor suppressor.\nMethods: In previously published work we reported on a global microarray screen which identified potential piRNA genes in non-small lung cancer cells over-expressing RASSF1C. We were able to detect several piRNAs that are modulated by RASSF1C. The expression of specific piRNAs that appear to be down or up-regulated by RASSF1C were confirmed by RT-PCR. We evaluated the impact of selected RASSF1C-target piRNAs on lung cancer cell proliferation and migration in vitro. We also have identified both host and target genes for specific piRNAs and have used piRNA mimics to down regulate target gene expression.\nResults: We show that piR-60643 is down regulated by RASSF1C and seems to function as a tumor suppressor in non-small cell lung cancer cells. Consistent with this, treatment of lung cancer cells with piR-60643 mimics reduced cell proliferation and migration, supporting the idea that piR-60643 could be a new inhibitor of lung cancer cell growth and progression. To learn more about how piR-60643 may hinder lung cancer cell growth, we searched for genes that could be targeted by piR-60643. Interestingly, we identified FABP5 as a piR-60643-target gene. FABP5 is up regulated in lung tumor tissue and in tissues of other cancers and is associated with poor patient survival. FABP5 plays a key role in regulating lipid metabolism and fatty acid oxidation (FAO). FAO is critical to supply the high energy (ATP) demand of rapidly growing cancer cells and contributes to cell cycle progression, EMT, migration, and metastasis. We found that treatment of lung cancer cells with piR-60643 mimics resulted in down regulation of FABP5 expression both at the mRNA and protein levels, implying that piR-60643 could disrupt FAO-associated metabolic pathway(s) in lung cancer cells. Interestingly, we found that PIWIL1 overexpression up-regulates FABP5 expression in lung cancer cells, suggesting that the PIWIL-FABP5 gene axis may play a role in lipid metabolism/FAO. This novel finding has not been previously reported.\nConclusion: Targeting FABP5 by piR-60643 could prove a novel mechanism of inhibiting lipid metabolism/FAO and impeding tumor growth and progression. As such, piR-60643 could prove to be a useful diagnostic/therapeutic tool for lung cancer.", "source_company": "Loma Linda VA Medical Center", "source_org_type": "医院", "row_number": 524, "target_meta": "FABP5", "MOA_meta": "其他"}, {"drug_name": "carnosic acid", "company": "Brock University", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 30.5, "institution_score": 25, "track_score": 35, "milestone_score": 30, "field_heat_score": 40, "bonus_score": 0, "brief_reason": "carnosic acid为天然多酚类化合物，通过诱导ROS并激活ASK1-MAPK信号通路发挥体外抗NSCLC作用，但靶点未明确披露。大学机构基础研究、早期机制探索、无明确开发信号导致整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/2862", "id": "wlXM_5wBX1NQZOEH-LG6", "source_drug_name": "carnosic acid", "title": "Carnosic acid induces ROS and activates ASK1 signalling in NSCLC cells", "abstract_text": "Carnosic acid (CA), a phenolic diterpene found in rosemary (Rosmarinus officinalis), has demonstrated anticancer activity in multiple tumor models; however, its mechanisms in non-small cell lung cancer (NSCLC) remain poorly defined. Many polyphenols exert biological effects through reactive oxygen species (ROS) generation and activation of apoptosis signal-regulating kinase 1 (ASK1)-mediated signalling, prompting this investigation into the role of ROS and ASK1 in the actions of CA. Cell viability was measured in NSCLC cells (H1299, A549, H460), and normal lung fibroblasts (MRC-5) following 48-hour CA treatment using the MTT assay. Migration of H1299 cells was assessed by scratch assay. ROS generation was quantified using dichlorodihydrofluorescin diacetate (DCFDA) fluorescence, and protein expression and activation were evaluated by western blotting and immunocytochemistry. CA decreased cell viability in a dose-dependent manner across NSCLC cell lines with IC50 in the micromolar range; H1299 showed the greatest sensitivity. In MRC-5 fibroblasts, maximal inhibition reached only ~50% of control compared with complete inhibition of growth observed in the NSCLC cell lines. In H1299 cells, CA significantly impaired wound closure after 24 hours, comparable to inhibition by paclitaxel. CA increased intracellular ROS levels and activated the antioxidant response pathway, evidenced by nuclear accumulation of nuclear factor erythroid 2-related factor 2 (Nrf2) and upregulation of heme oxygenase-1 (HO-1). Western blotting demonstrated activation of ASK1 and downstream mitogen-activated protein kinases (MAPK), including extracellular signal-regulated kinase (ERK), c-Jun N-terminal kinase (JNK), and p38. Pretreatment with N-acetylcysteine (NAC) attenuated CA-induced cytotoxicity, supporting a role for ROS in mediating these effects. In summary, carnosic acid inhibits viability and migration of NSCLC cells while partially sparing normal lung fibroblasts. Its effects involve ROS generation and activation of ASK1-dependent MAPK signaling. These findings provide mechanistic insight into the anticancer potential of CA in lung cancer. Future work will evaluate CA using an in vivo tumor xenograft model.", "source_company": "Brock University", "source_org_type": "大学", "row_number": 447, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "nanoliposomes with optimized cholesterol concentration and lipid extract derived from a model low grade serous ovarian carcinoma cell line", "company": "Massachusetts College of Pharmacy and Health Sciences", "org_type": "大学", "target": "未披露", "modality": "nanoliposomes", "importance_level": "低", "total_score": 30.5, "institution_score": 25, "track_score": 40, "milestone_score": 25, "field_heat_score": 35, "bonus_score": 0, "brief_reason": "该纳米脂质体利用LGSOC细胞系脂质提取物优化胆固醇浓度，旨在提高对LGSOC细胞的摄取，但靶点和具体机制未明确披露，仅处于早期体外优化阶段。大学机构、非热门modality、preclinical早期且无明确突破导致总体评分较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5568", "id": "E1XM_5wBX1NQZOEH-LK6", "source_drug_name": "nanoliposomes with optimized cholesterol concentration and lipid extract derived from a model low grade serous ovarian carcinoma cell line", "title": "Cellular uptake of nanoliposomes with optimized cholesterol concentration and lipid extract derived from a model low grade serous ovarian carcinoma cell line", "abstract_text": "Introduction: Low-grade serous ovarian carcinoma (LGSOC) represents a rare subtype of epithelial ovarian cancer, accounting for less than 10% of all cases and typically diagnosed in younger women. The disease is characterized by tumor growth driven by activating mutations in the MAPK pathway, including KRAS, BRAF, and NRAS. Despite its slow progression, LGSOC remains challenging to treat due to limited responsiveness to conventional chemotherapy. The objective of this study was to isolate cellular lipid extract (LE) material from a model LGSOC cell line, and to utilize the newly acquired LE material to develop a relatively target specific nanoliposomal system. Early formulation and in vitro studies include optimization for cholesterol and LE content.\nMethods: Low-grade serous ovarian carcinoma cell line (PM-LGSOC-01, Cytion) was cultured and expanded in EMEM growth medium supplemented with 10% FBS. The PM-LGSOC-01-lipid extract (LE) material was extracted from PM-LGSOC-01 when the cells reached ~90% confluency. Lipid extraction was performed as described previously (Alharbi & Campbell, AAPS Open, number: 5(2018)). Nanoliposomal preparations consisted of DOPC, cholesterol, and LE at various ratios and wereformed by thin film method using a Buchi R-80 rotary evaporator. DPPE-Rhodamine was included in the preparations for cellular studies. Following sonication, particle size and zeta potential values weredetermined using ZetaPals. Fluorescence detection was performed using a fluorescence microplate reader.\nResults: Three preparations (1) DOPC (100%), (2) DOPC/Chol (95/5), and (3) DOPC/Chol (90/10) wereprepared with an average particle size of 221 ± 3 nm, 250 ± 5 nm, and 139 ± 0.3 nm, respectively. Preliminary results suggest that the additional inclusion of cholesterol in the nanoliposomal preparations increased their uptake by the target (PM-LGSOC-01) cells. Studies investigating the influence of PM-LGSOC-01-LE on the uptake of nanoliposomes by the target cells are currently underway.\nConclusion: To date, the influence of cholesterol on the uptake of nanoliposomes by LGSOC cells has been investigated. Future studies will evaluate the effect of optimized cholesterol and LE contenton targeting low-grade serous ovarian carcinoma.", "source_company": "Massachusetts College of Pharmacy and Health Sciences", "source_org_type": "大学", "row_number": 504, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "Gli2 inhibitor", "company": "Vanderbilt University", "org_type": "大学", "target": "Gli2", "modality": "inhibitor", "importance_level": "低", "total_score": 30.5, "institution_score": 25, "track_score": 45, "milestone_score": 20, "field_heat_score": 40, "bonus_score": 0, "brief_reason": "Gli2抑制剂针对Hedgehog通路下游转录因子Gli2，旨在调控TNBC中EMT和侵袭，目前仅为大学基础研究阶段。机构非商业公司且无明确临床前候选化合物推进，赛道非当前最热门，导致总体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6057", "id": "Sp7ECZ0BZznHJdntvNYd", "source_drug_name": "Gli2 inhibitor", "title": "Gli2 regulation of EMT in TNBC invasion", "abstract_text": "Despite improvements in survival for patients with primary disease only, breast cancer remains a leading cause of cancer-related death for women in part due to the propensity of breast cancer to metastasize and develop therapy resistance. Triple negative breast cancer (TNBC) has high metastatic potential, and an estimated 30-50% of patients develop tumors that are resistant to chemotherapies. To metastasize, tumors undergo epithelial-to-mesenchymal transition (EMT), in which transcriptional alterations allow tumor cells to become more invasive through reduced adhesion and increased motility. In addition to facilitating the early stages of metastasis and allowing tumors to invade, EMT has been associated with a more plastic, stem-like phenotype that may lead to therapy resistance. Thus, preventing the acquisition of an EMT phenotype may offer a dual role in inhibiting metastatic potential as well as resensitizing therapy-resistant tumors in patients with TNBC. While the Hedgehog (HH) signaling pathway is primarily active during embryonic development, its aberrant activation has been observed to promote tumor growth, invasion, metastasis, and chemoresistance. Previous data have shown that components of the HH pathway are upregulated in clinical samples of breast cancer in patients with greater mesenchymal gene signatures and those with metastatic disease. Additionally, Gli2 (Glioma-associated oncogene 2), a downstream transcriptional regulator of HH signaling, correlates with poorer patient outcomes. Thus, we hypothesize that Gli2 transcriptionally regulates EMT-associated genes, therefore promoting invasive potential in TNBC. We examined the pharmacological inhibition of Gli2 and found a reduction in EMT marker expression in TNBC cell lines. Specifically, we have identified genes such as Cldn1 (FC = 0.382, p = 0.0003), Zeb2 (FC = 0.426, p = 0.0005), and Spp1 (FC = 0.163, p = 0.0009) as potential targets of Gli2-mediated EMT. We will use Cleavage Under Targets & Release Using Nuclease (CUT&RUN) sequencing to identify regions of DNA bound by Gli2, followed by comparison to genes that have differentially expressed RNA transcripts upon inhibition of Gli2. Following confirmation of Gli2-regulation of EMT-associated genes, we will genetically knockdown these target genes in Gli2-overexpressing TNBC cell lines and overexpress these genes in Gli2-knockdown TNBC cell lines. We will then perform transwell migration and invasion assays as well as ex vivo invasion assays on decellularized extracellular matrix (dECM) scaffolds from mouse mammary fat pads using the above cell models to assess the rescue or depletion of EMT phenotypes. The proposed studies will provide insight into the mechanisms by which Gli2 regulates EMT and invasion in TNBC. Elucidating direct transcriptional regulation of Gli2 on the EMT program may provide insight into potential therapeutic targets to reduce metastatic burden and combat chemoresistance in TNBC patients.", "source_company": "Vanderbilt University", "source_org_type": "大学", "row_number": 571, "target_meta": "GLI2", "MOA_meta": "抑制剂"}, {"drug_name": "dibutyl organotin(IV) complex", "company": "University of Iceland", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 30.5, "institution_score": 25, "track_score": 30, "milestone_score": 35, "field_heat_score": 40, "bonus_score": 0, "brief_reason": "该二丁基有机锡(IV)络合物为新型金属化合物，主要通过靶向DNA诱导DNA损伤、细胞周期阻滞和凋亡产生抗肿瘤效应，但靶点未明确披露。机构为大学、处于早期体外研究阶段、赛道非热门导致总体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8763", "id": "OlXM_5wBX1NQZOEH-LS6", "source_drug_name": "dibutyl organotin(IV) complex", "title": "DNA damage, apoptosis and cell cycle disruption: Antitumor effects of a novel tin(IV) complexes", "abstract_text": "Introduction: Platinum-based chemotherapeutics like cisplatin are widely used against cancer but are limited by toxicity and drug resistance. Organotin(IV) complexes offer a promising alternative with enhanced efficacy and distinct mechanisms. Here, we evaluated the anticancer activity of dibutyl and diphenyl organotin(IV) complexes and investigated their mechanisms of action across multiple cancer cell lines.\nMaterial and Method: Synthesis of Organotin(IV) Complexes: Dibutyl and diphenyl organotin(IV) (Bu-Sn and Ph-Sn) complexes were synthesized following established protocols. The purity and structural confirmation of the complexes were verified using spectroscopic techniques. Anti-cancer activities: The following human cell lines were used in this study: T-47D (breast carcinoma), HCT116 (colorectal carcinoma), AsPC-1 (pancreatic adenocarcinoma), and MCF-10A (non-tumorigenic mammary epithelial). Following manufactures protocol MTT assay is utilized for the determination of half maximum inhibitory concentration (IC50). The mode of cell death (apoptosis and necrosis) investigated in cell lines via flow cytometry using the Annexin V and propidium iodide (PI) staining method. Analysis of cell cycle with flow cytometry performed to determine the changes in the cell cycle for each cell lines utilizing cisplatin as a reference drug. Subcellular distribution of the organotin(IV) complexes was evaluated by ICP-MS. Treated cells were fractionated into major cellular compartments to determine the predominant localization of the complexes. DNA damage induced by the organotin(IV) complexes was assessed using the Comet assay, allowing quantification of treatment-related DNA strand breaks.\nResults and Discussion: Bu-Sn exhibited strong cytotoxic activity across all tested cancer cell lines (IC₅₀ < 3.00 µM), with particularly high potency against T-47D human breast cancer cells (IC₅₀ = 0.53 µM). Importantly, it showed minimal toxicity toward non-cancerous MCF-10 cells, demonstrating a favorable level of selectivity. In contrast, Ph-Sn displayed only limited cytotoxic activity. Mechanistically, Bu-Sn induced G1 phase arrest and triggered dose-dependent apoptosis in T-47D cells. Subcellular analysis revealed predominant nuclear accumulation (32% for Bu-Sn, 24% for Ph-Sn), correlating with pronounced DNA damage observed in Comet assays, suggesting that nuclear targeting and genotoxic stress underlie its anticancer activity.\nConclusion: Two organotin(IV) complexes containing dibutyl and diphenyl groups were synthesized and fully characterized. The dibutyl complex exhibited strong cytotoxic activity across multiple cancer cell lines while sparing non-malignant cells. Mechanistic studies indicated that these tin complexes primarily target DNA, inducing cell cycle arrest and apoptosis, ultimately leading to cancer cell death.", "source_company": "University of Iceland", "source_org_type": "大学", "row_number": 873, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "V3", "company": "University of Oklahoma", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 30.5, "institution_score": 25, "track_score": 35, "milestone_score": 30, "field_heat_score": 40, "bonus_score": 0, "brief_reason": "V3为pH-responsive插入肽，可在酸性微环境中发生构象变化用于靶向PDAC，但靶点未明确披露，仅为工具性研究优化MMS检测方法。机构为大学、非热门modality且无临床开发进展，导致整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6529", "id": "UVXM_5wBX1NQZOEH-LS6", "source_drug_name": "V3", "title": "Optimizing the detection of pH-dependent conformational changes in pH-low insertion peptides using microfluidic modulation spectroscopy (MMS)", "abstract_text": "Introduction: The acidic microenvironment of pancreatic ductal adenocarcinoma (PDAC) can be targeted by pH-responsive peptides that undergo conformational changes upon protonation of their negatively charged residues. While microfluidic modulation spectroscopy (MMS) has been successfully used to detect higher-order structure in large proteins, there is room for optimization in the reliable detection of secondary structure for small peptides (< 30 amino acids). We utilized two pH-responsive peptides, V7 and V3, and an inactive peptide, K7, to investigate the effects of buffer conditions and the presence of liposomes on the ability of MMS to detect pH-based conformational changes in these small peptides.\nMethods: Peptides were synthesized using the CEM LibertyBlue microwave technology. 10 mM and 20 mM phosphate buffer solutions (PBS) were prepared at pH 7.4 and 6.6. Liposomes were prepared using the thin film hydration technique, and then characterized with dynamic light scattering (DLS) to find size, polydispersity index, and surface potential. The RedShiftBio Aurora MMS system was used to analyze the secondary structure of V7, V3, and K7 at either pH 7.4 or 6.6 PBS with liposomes or without liposomes. Each buffer solution was prepared with 1 mg/mL of peptide and sonicated for 30 minutes before MMS reading. RedShiftBio higher-order structure and Gaussian analysis software were used to compare conformational changes between pH 7.4 to 6.6 for each peptide in the various buffer conditions.\nResults: DLS revealed the liposomes to be 122 nm with a polydispersity index of 0.207 and a surface potential of +32.9 mV. The expected conformational changes for V7 and V3 based on pH could not be adequately detected without the presence of liposomes in the solution. 10 mM PBS with a concentration of 106 liposomes per mL was the optimal solution for characterizing the peptides, with V7 and V3 experiencing an increase in alpha-fold at pH 6.6 compared to 7.4, and K7 experiencing either no change or less alpha-fold at pH 6.6 compared to 7.4.\nConclusion: A low salt concentration solution containing liposomes was the ideal environment for the peptides V7 and V3 to undergo a pH-dependent conformational change that could be detected by MMS. MMS is a relatively quick method for determining peptide secondary structure with a low limit of quantification.\nFunding: R01CA2810190", "source_company": "University of Oklahoma", "source_org_type": "大学", "row_number": 888, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "Oliphenolia®", "company": "European Institute of Oncology", "org_type": "医院", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 30.5, "institution_score": 25, "track_score": 35, "milestone_score": 30, "field_heat_score": 40, "bonus_score": 0, "brief_reason": "Oliphenolia®为橄榄油副产物多酚富集提取物（主要含羟基酪醇），属天然抗氧化/抗炎营养补充剂，无明确药物靶点。机构为医院而非药企、处于早期探索性单臂试验阶段且样本量小、赛道为营养保健品而非主流创新药物，导致整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/966", "id": "Sp7M_5wBZznHJdnt_W3O", "source_drug_name": "Oliphenolia®", "title": "Effects of olive oil byproducts polyphenol reach extract on muscle function, sarcopenia-related parameters and skin health", "abstract_text": "Sarcopenia, the age-related loss of skeletal muscle mass, strength, and function, represents a major determinant of frailty and disability in older adults. Nutraceutical strategies targeting inflammation and oxidative stress have been proposed as adjunctive countermeasures. Olive mill wastewater (OMWW), a byproduct of olive oil production, is rich in hydroxytyrosol and other polyphenols with potent antioxidant and anti-inflammatory effects. Results from a 30-day, single-arm pilot trial to evaluate several biometric and anthropometric parameters, after assumption of the OMWW extract, OMWW-OL (Oliphenolia®), revealed a positive trends to ameliorate sarcopenia-related values in adults with metabolic syndrome, a population at elevated risk for muscle decline. Twenty-nine participants were enrolled, and 23 (15 men, 8 women) completed the study. Assessments included bioimpedance-derived indices of muscle mass, anthropometry, handgrip strength, calf circumference, hydration, and inflammatory/metabolic markers at baseline (T0), after supplementation (T1), and 30 days post-intervention (T2). OMWW-OL was well tolerated. Participants showed modest but consistent trends toward improved fat-free mass index (FFMI), appendicular skeletal muscle mass (ASMM), and handgrip strength at T1, with partial persistence at T2. Calf circumference increased steadily across the observation period. Among biochemical markers, oxidized LDL (oxLDL), a lipid peroxidation indicator linked to muscle catabolism, showed a small but progressive reduction from T0 to T2, consistent with the antioxidant profile of OMWW polyphenols, whereas CRP exhibited a transient rise at T1 before returning near baseline at T2.Although statistical significance was limited by small sample size and study design, the observed trends align with preclinical evidence that OMWW polyphenols mitigate oxidative stress, suppress pro-inflammatory cytokines, and promote muscle protein homeostasis. These exploratory findings justify larger randomized trials to evaluate OMWW as a nutraceutical strategy for sarcopenia prevention and management. Sarcopenia has been also associated with cancer, is higher in oncology patients with metabolic syndrome and worsens response to therapy. Cosmeceutical preparations using OMWW-OL also reveal protective properties for the skin. One of the major polyphenols in OMWW-Ol is hydroxytyrosol, and investigations are ongoing oh the role of the purified substance.", "source_company": "European Institute of Oncology", "source_org_type": "医院", "row_number": 998, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "carnosic acid", "company": "Brock University", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 30.5, "institution_score": 25, "track_score": 35, "milestone_score": 30, "field_heat_score": 40, "bonus_score": 0, "brief_reason": "carnosic acid为天然植物来源化合物，通过激活AMPK信号通路抑制乳腺癌细胞增殖并诱导凋亡和自噬，但靶点未明确披露。大学机构基础研究阶段，创新性和开发性有限，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6074", "id": "eZ7M_5wBZznHJdnt_W3O", "source_drug_name": "carnosic acid", "title": "Carnosic acid inhibits proliferation and induces apoptosis of breast cancer cells", "abstract_text": "Breast cancer remains a major cause of cancer-related mortality among women worldwide, contributing to an estimated 670,000 deaths in 2022. Although advances in early detection and systemic therapy have improved outcomes, incidence rates continue to rise, and therapeutic resistance—particularly in aggressive subtypes such as triple-negative breast cancer (TNBC)—remains a critical challenge. Plant-derived chemicals have historically served as a source of anticancer agents, exemplified by the clinical success of paclitaxel, highlighting the continued potential of plant-derived compounds.In this study, we examined the anticancer effects of carnosic acid (CA), a polyphenolic diterpene abundant in rosemary, sage, and oregano, across multiple breast cancer subtypes. CA significantly suppressed proliferation of TNBC cell lines (MDA-MB-231, HCC70, HCC1143) and Luminal A cell lines (MCF7, T47D) in a dose-dependent manner with IC₅₀ values in the range of 30 to 78 μM, (MDA-MB-231: 77.92 μM; HCC70: 63.51μM; HCC1143: 38.56 μM; T47D: 30.29μM).CA induced apoptotic cell death, confirmed by increased Annexin V/PI staining and elevated levels of cleaved PARP in MDA-MB-231, MCF7, and T47D cells. Additionally, CA promoted autophagy, demonstrated by enhanced LC3A/B-II accumulation and increased Beclin-1 expression.These anti-proliferative and pro-apoptotic effects of CA were associated with robust activation of AMP-activated protein kinase (AMPK) signaling, as evidenced by increased phosphorylation of AMPK and its downstream target, acetyl-CoA carboxylase (ACC).Collectively, these data indicate that carnosic acid suppresses breast cancer cell proliferation, induces apoptosis and autophagy with a concomitant AMPK activation. These findings support CA as a promising plant-derived therapeutic candidate and justify further evaluation in in vivo breast cancer models.", "source_company": "Brock University", "source_org_type": "大学", "row_number": 1032, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "statins", "company": "Hong Kong Baptist University", "org_type": "大学", "target": "未披露", "modality": "inhibitor", "importance_level": "低", "total_score": 30.2, "institution_score": 20, "track_score": 40, "milestone_score": 35, "field_heat_score": 45, "bonus_score": 2, "brief_reason": "statins为HMG-CoA还原酶抑制剂，通过扰乱谷胱甘肽代谢诱导铁死亡相关脆弱性，但摘要未明确其直接药物靶点，仅揭示CRC中GCLC上调及GPX4依赖的代偿机制。大学机构非主流药企、preclinical水平无明确临床里程碑、药物重定位赛道热度中等，导致总分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9072", "id": "XlXM_5wBX1NQZOEH-LS6", "source_drug_name": "statins", "title": "Repurposing statins activates compensatory glutathione metabolism as synergistic vulnerability in colorectal cancer", "abstract_text": "Metabolic adaptations upon intrinsic and environmental stressors enable cancer cells to resist treatment and sustain proliferation. Understanding of adaptive rewiring and compensatory mechanisms is a pivotal strategy to develop effective treatment options. Statins are receiving increasing attention in the prevention of colorectal cancer (CRC), but the biological mechanism is elusive. Here, we demonstrate that six statins show effective tumor repression capacity in a dose-dependent manner. We next observe that administration of statin alone is not sufficient to induce programmed cell death because inhibitors of ferroptosis, apoptosis, necroptosis, and autophagy fail to rescue the cell viability. To further understand the therapeutic vulnerability, untargeted metabolic analysis is employed to detect the reprogramming metabolites. Pathway analysis shows glutathione metabolism is significantly perturbed. Meanwhile, dramatic increases of cysteine and gamma-glutamylcysteine are widely observed while the reduced glutathione (GSH) and oxidized glutathione (GSSG) levels are decreased, linked to redox imbalance and ferroptosis. Western blotting shows statins have similar effects as RSL3 on increasing the expression of glutamate-cysteine ligase catalytic subunit (GCLC), which catalyzes the rate-limiting step of GSH synthesis, and its inhibition is associated with ferroptosis induction. In contrast, CRC cells show increasing reliance on glutathione peroxidase 4 (GPX4) upon statins treatment when compare to RSL3. Collectively, compensatory upregulation of GCLC indicates combinations of statins and GCLC inhibitors may enhance antiproliferative efficacy of targeting GSH metabolism.", "source_company": "Hong Kong Baptist University", "source_org_type": "大学", "row_number": 894, "target_meta": "not available", "MOA_meta": "抑制剂"}, {"drug_name": "ergosterol peroxide", "company": "Universidad Central del Caribe", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 30, "institution_score": 25, "track_score": 35, "milestone_score": 30, "field_heat_score": 40, "bonus_score": 0, "brief_reason": "ergosterol peroxide为天然产物，在TNBC细胞中通过干扰蛋白质稳态（抑制蛋白合成、诱导线粒体功能障碍、增加蛋白聚集、降低泛素水平）发挥选择性抗癌作用，但靶点未明确披露。机构为大学、处于早期机制探索阶段、无明确临床开发迹象，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8841", "id": "p1XM_5wBX1NQZOEH-LK6", "source_drug_name": "ergosterol peroxide", "title": "Effects of ergosterol peroxide on proteostasis disruption in triple negative breast cancer cells", "abstract_text": "Triple-negative breast cancer (TNBC) is a highly aggressive and heterogeneous subtype of breast cancer characterized by the absence of estrogen receptor, progesterone receptor, and HER2 expression, known for its high malignancy, invasiveness, and propensity for metastasis. Due to the lack of targeted therapies, TNBC patients typically undergo multimodality chemotherapy with cytotoxic agents like taxanes, anthracyclines, and cyclophosphamide. Therefore, there is an urgent need for selective therapies for TNBC. Natural products have gained significant attention for their potential in cancer therapy, as around 60% of clinically approved anticancer drugs were inspired by secondary metabolites found in nature. In our laboratory, we work with Ergosterol Peroxide (EP), a bioactive compound extracted from the Ganoderma lucidum mushroom. We discovered that the natural product EP exhibits selective cytotoxicity against TNBC models, demonstrating activity in the low micromolar range while sparing normal cells. Our studies indicate that EP exerts its anticancer effects by disrupting critical cellular processes including proteostasis, protein synthesis, and protein degradation pathways. We hypothesize that EP compromises TNBC cell viability by disrupting proteostatic balance. Mechanistically, we propose that EP inhibits protein synthesis and induces mitochondrial dysfunction, which collectively impair the ability of TNBC cells to restore protein homeostasis, ultimately resulting in cell death. To validate our hypothesis, we performed protein synthesis assays in two TNBC cell models, SUM149 and MDA-MB-231. Veh (0.2% DMSO), EP (20μM), or cyclophosphamide (1μM, positive control) were administered for 6 or 24h. EP effects on protein aggregation, under Veh, EP, or MG132 (positive control) in SUM149 or MDA-MB-231 TNBC cells and MCF10A non-cancerous cells, we used an aggresome assay. Finally, to assess protein degradation we performed western blots probing for ubiquitin. We previously established that EP increases ROS levels in TNBC cells. EP affects protein synthesis, compared to negative vehicle control treated cells, and in reduced capacity when compared to cyclophosphamide. Moreover, EP significantly increases protein aggregation, although the signal detected for MG132 was greater. Finally, EP decreases cancer cell degradation, as seen by decreased levels of ubiquitin when treated after 24h. In summary, EP demonstrates the capacity to modulate proteostasis in TNBC cells. Further investigation is warranted to comprehensively characterize the intricate mechanistic pathways by which EP exerts its anticancer effects in this malignancy.", "source_company": "Universidad Central del Caribe", "source_org_type": "大学", "row_number": 592, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "Asparagus Racemosus root extract", "company": "South Dakota State University", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 30, "institution_score": 25, "track_score": 30, "milestone_score": 35, "field_heat_score": 40, "bonus_score": 0, "brief_reason": "Asparagus Racemosus根提取物（Shatavari）为天然植物提取物，未明确特定分子靶点，主要通过调控乳腺组织架构和信号通路（如MTHFD1、MAP4K4下调）显示TNBC预防和分化诱导潜力。机构为普通大学、modality非热门赛道、仅早期动物实验，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6758", "id": "fVXM_5wBX1NQZOEH-LO6", "source_drug_name": "Asparagus Racemosus root extract", "title": "Mammary gland architectural modulation with a natural galactagogue Asparagus racemosus (Shatavari root extract) and its impact against triple negative breast cancer (TNBC) tumorigenesis", "abstract_text": "The roots of Asparagus Racemosus Willd. (Shatavari) are known for its galactagogue properties and often used as a traditional/ alternative way to increase milk production during lactation and for breast size augmentation. There is also supporting evidence that it has anti-cancer properties against various cancers including carcinogen-induced breast cancer in pre-clinical in vivo studies and against ER positive breast cancer cell lines. In the present study we investigated the anti-cancer potential of standard extract of roots of Asparagus Racemosus (ARRE) against triple negative breast cancer (TNBC). We conducted orthotopic tumorigenesis studies in C57Bl/6 female mice. Five weeks old C57Bl/6 female mice (Jackson Labs), were maintained on control AIN-76A diet from Envigo diets, Inc. After 1 week of acclimatization mammary tumors were induced by orthotopic injection of 2x106 PY230 breast cancer cells in the 4th mammary fat pad (either left or right) on day 0. n=7 mice per group were treated with or without ARRE as an oral intervention agent (including with and without tumor inoculation). The dose of ARRE was 250 mg/kg body weight/day (volume 200μl sterile distilled water)-prepared fresh daily. Study end point was 8 weeks following cell inoculations. At study end, tumor tissues, tumor adjacent breast fat pad was harvested from mice and processed for pathological/ molecular analysis. ARRE treatment caused an increase in latency time (time taken for appearance of palpable TNBC tumors) indicating its preventive benefits. ARRE treatment did not have any significant impact on TNBC tumorigenesis; however, tumors had the appearance of differentiated lobular/glandular formation in ARRE -fed groups compared to undifferentiated tumor cells in the controls. Proteomic profiling of mammary gland tissues indicated there were 43 differentially expressed biomarkers after ARRE intervention. Out of the 43 differentially expressed biomarkers, there were 2 molecules [Methylenetetrahydrofolate dehydrogenase 1 (MTHFD1) and Mitogen-activated protein kinase kinase kinase kinase 4 (MAP4K4) that were significantly decreased in the ARRE control (treated tissue). Importantly, these two molecules are reported to be overexpressed in breast cancer and implicated in the growth and progression of breast cancer. Overall, the results indicated that ARRE intervention results in modulation of signaling pathways (that are associated with breast cancer growth and progression) and had the potential to induce differentiation in TNBC tumors, which could possibly be a novel approach to target TNBC malignancy. Taken together, the study outcomes favor the use of ARRE as a preventive or therapeutic modality against TNBC but warrants further investigation.", "source_company": "South Dakota State University", "source_org_type": "大学", "row_number": 733, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "nanoliposomal formulation", "company": "Massachusetts College of Pharmacy and Health Sciences", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 30, "institution_score": 25, "track_score": 40, "milestone_score": 25, "field_heat_score": 35, "bonus_score": 0, "brief_reason": "该nanoliposomal formulation为脂质体递送系统优化研究，未明确具体药物或靶点，仅探讨胆固醇含量对葡萄膜黑色瘤细胞摄取的影响。机构为大学、非热门赛道、仅preclinical初步机制探索导致总体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5540", "id": "lFXM_5wBX1NQZOEH-LS6", "source_drug_name": "nanoliposomal formulation", "title": "Evaluating the influence of cholesterol content on the cellular uptake and formulation activity of nanoliposomal formulations against uveal melanoma", "abstract_text": "Introduction: Uveal melanoma (UM) is a rare but aggressive intraocular malignancy with limited responsiveness to current therapies. Nanoliposomal delivery systems can enhance intracellular drug transport, but their performance depends on lipid composition and the tumor’s metabolic profile. UM exhibits dysregulated cholesterol metabolism driven by altered expression of enzymes such as SREBP2. Because cholesterol is a key structural membrane component that influences liposome properties, this study evaluated how cholesterol inclusion affects nanoliposome uptake and drug effects in UM cells.\nMethodology: MP41 uveal melanoma cells (ATCC®) were cultured in RPMI supplemented with 25% FBS. Cells (2×10⁴/mL) were seeded in vented centrifuge tubes and exposed to DPPE-rhodamine-labeled nanoliposomes containing 0, 5, 10, or 20 mol% cholesterol substituted for DOPC. Tubes were placed in an oscillating incubator at 37 °C for 60 minutes to promote liposome-cell interactions. Cellular uptake was quantified using a fluorescence microplate reader, and Quad Count™ was used for cell counting, viability, and growth-inhibition assessments.\nResult: At 1 hour, the inclusion of cholesterol decreased the uptake of nanoliposomes by MP41 uveal melanoma cells. DOPC consistently demonstrated the highest cellular uptake values (≈2594-4543 RFU), while 95/5 and 90/10 formulations displayed lower values (≈800-3451 RFU) by comparison. These findings reveal a reproducible inverse relationship between cholesterol content and cellular uptake, suggesting that the inclusion of cholesterol in nanoliposome diminishes cellular uptake. Ongoing studies will evaluate additional time points and conditions, and whether the findings correlate with cytotoxicity studies.\nConclusion: Reduced cholesterol content in nanoliposomal formulations markedly enhanced cellular uptake by uveal melanoma cells. The consistently higher internalization observed with DOPC (100%) supports the use of relatively low-cholesterol (or cholesterol-free) preparations to enhance targeting. Cholesterol modulation could potentially enhance the effectiveness of therapeutics against uveal melanoma.", "source_company": "Massachusetts College of Pharmacy and Health Sciences", "source_org_type": "大学", "row_number": 938, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "Block lipid transport 1", "company": "Morehouse School of Medicine", "org_type": "大学", "target": "SR-B1", "modality": "inhibitor", "importance_level": "低", "total_score": 29.5, "institution_score": 25, "track_score": 40, "milestone_score": 20, "field_heat_score": 30, "bonus_score": 0, "brief_reason": "药品为SR-B1抑制剂BLT-1，在三阴性乳腺癌细胞系中研究高糖环境下药物敏感性变化，靶点为脂质代谢相关受体。机构为大学学术型，非商业研发，处于基础体外研究阶段，无明确临床开发里程碑，赛道非当前热门，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6554", "id": "d57M_5wBZznHJdnt_W3O", "source_drug_name": "Block lipid transport 1", "title": "SR-B1 gene variants, inhibitors and the effect of glucose on IC50s in breast cancer", "abstract_text": "Background: Ancestry-related genetic variations have been observed to influence the risk of certain cancers and diabetes through inherited genetic variations and their interaction with lifestyle and environment. Type 2 diabetes has been considered a risk factor for breast cancer, thus suggesting metabolism may drive cancer progression. The reverse cholesterol transporter and membrane receptor Scavenger receptor B1 (SR-B1), which is involved in insulin resistance and lipid metabolism, with its ancestry enriched variants, is evaluated in breast cancer as a novel target.\nMethods: The triple negative breast cancer cell lines MDA.MB 231 and MDA.MB 468 were employed for this study. SNP genotyping to determine the genotype of each cell line was performed using the TaqMan SNP Genotyping assays for the SR-B1 missense SNP variant rs2293440. Cells were grown in media with varying glucose levels of 5.5 mM, 17.5 mM and 25 mM, representative of the blood glucose level indicator HbA1C. The cells were then treated with different concentrations of the SR-B1 inhibitor drug, Block lipid transport 1 (BLT-1), for total of 48 hours. After 48 hours, cell survivability assay was used to determine percent survival for each cell line under the conditions mentioned.\nResults: The SNP genotyping results indicated that MDA.MB 231 contained the wild-type allele while MDA.MB 468 contained the variant allele. Results of the cell survivability assay showed that sensitivity of both the cell lines to BLT-1 was increased by 3-fold and 5-fold at 5.5 mM glucose concentration in media for MDA.MB 231 and 468 respectively, as was confirmed by the IC50 values. Both cell lines displayed resistance to BLT-1 at the higher media glucose concentrations of 17.5 and 25 mM with their IC50 values exhibiting up to a 5-fold increase. Further, MDA.MB 468 displayed almost 2-fold higher sensitivity to BLT-1 at both 5.5 mM and 17.5 mM media glucose concentration in comparison to MDA.MB 231.\nConclusions: These results indicate that there is a correlation between the blood glucose levels and the drug sensitivity or drug response in cancer. Further, our results suggest that the response to metabolism inhibitor drugs in cancer and glucose metabolism may also be impacted by the ancestry and genetic variation of an individual.", "source_company": "Morehouse School of Medicine", "source_org_type": "大学", "row_number": 1030, "target_meta": "SCARB1", "MOA_meta": "抑制剂"}, {"drug_name": "beta-hydroxybutyrate", "company": "Chaminade University of Honolulu", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 29.5, "institution_score": 25, "track_score": 40, "milestone_score": 20, "field_heat_score": 45, "bonus_score": 0, "brief_reason": "beta-hydroxybutyrate为内源性酮体代谢物，非靶向药物，仅在体外模拟生酮状态下研究ER+乳腺癌代谢重编程。机构为大学、处于基础研究阶段、无明确药物开发里程碑，故整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/9095", "id": "o53ECZ0B4z9FlvORyiZD", "source_drug_name": "beta-hydroxybutyrate", "title": "Beta-hydroxybutyrate alters one-carbon and branched-chain amino acid metabolism in glucose-restricted ER+ breast cancer cells", "abstract_text": "Ketogenic diet interventions show promise in breast cancer treatment, yet precise metabolic adaptations remain incompletely characterized. We investigated amino acid metabolic reprogramming in estrogen receptor-positive (ER+) breast cancer cells subjected to glucose restriction with beta-hydroxybutyrate (BHB) supplementation to model ketogenic conditions. MCF-7 and T47D cells were cultured in glucose-restricted medium (5% standard concentration) with graded BHB supplementation (2.5-15 mM) for four days. Metabolomic profiling was performed using comprehensive two-dimensional gas chromatography-mass spectrometry (GC×GC-MS) with Fisher ratio analysis. Targeted quantification of glycine and branched-chain amino acids (BCAAs) was conducted using colorimetric and fluorometric assays. SHMT1 protein expression was measured by ELISA. Bioinformatic analysis of TCGA Breast Invasive Carcinoma data (n=1,084) assessed co-expression patterns between one-carbon metabolism genes (SHMT1/2), BCAA metabolism (BCAT1), and ketone body catabolic enzymes (OXCT1, ACAT1, BDH1). Differential expression analysis was performed on paired ER+ tumor and adjacent normal tissue samples (n=20) from GSE58135. R-code for DEG analysis was partially created using Anthropic Claude (version Sonnet 4.5). Metabolomics analysis revealed significant perturbations in one-carbon and BCAA metabolism pathways. Direct quantification confirmed dose-dependent glycine accumulation, with peak elevation at 5 mM BHB in both MCF-7 (51.1±29.5 μM vs. 27.7±3.9 μM low glucose, p<0.05) and T47D cells (40.7±9.8 μM vs. 29.6±9.5 μM, p<0.05). Despite altered glycine levels, SHMT1 protein expression remained stable across treatments in both cell lines. TCGA analysis showed weak positive correlations between SHMT1 and ketone catabolic genes BDH1 (r=0.18, p=2.88×10⁻⁹) and ACAT1 (r=0.05, p=0.133), while BCAT1 showed moderate negative correlation with BDH1 (r=-0.36, p=3.69×10⁻³⁵). Differential expression analysis revealed significant downregulation of OXCT1 (log2FC=-1.41, p=5.75×10⁻⁷), SHMT1 (log2FC=-1.31, p=1.62×10⁻⁵), and ACAT1 (log2FC=-1.07, p=1.07×10⁻⁴) in ER+ tumors versus normal tissue, indicating selective suppression of ketone catabolism and cytoplasmic one-carbon metabolism. BHB supplementation under glucose restriction induces specific alterations in glycine homeostasis without corresponding SHMT1 changes, suggesting post-translational regulation or altered metabolic flux. Downregulation of ketone catabolic enzymes in ER+ tumors may represent a metabolic vulnerability exploitable through ketogenic interventions, warranting investigation of one-carbon metabolism as a therapeutic target in ER+ breast cancer.", "source_company": "Chaminade University of Honolulu", "source_org_type": "大学", "row_number": 1039, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "Camu camu", "company": "Instituto Nacional de Cancerología", "org_type": "医院", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 29, "institution_score": 20, "track_score": 40, "milestone_score": 30, "field_heat_score": 40, "bonus_score": 3, "brief_reason": "Camu camu 为富含多酚的亚马逊浆果，在此作为益生元补充剂与nivolumab/ipilimumab联合用于mRCC一线治疗，机制为调控肠道菌群增强免疫治疗效果，但药品本身无明确药物靶点。机构为医院类型、处于随机I期试验早期探索阶段、赛道为菌群调控辅助热门免疫治疗但非主流药物开发，导致综合评分较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/12088", "id": "6VXM_5wBX1NQZOEH-LO6", "source_drug_name": "Camu camu", "title": "Camu camu plus nivolumab/ipilimumab (N/I) as first-line therapy for metastatic renal cell carcinoma (mRCC): A randomized phase I trial", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Instituto Nacional de Cancerología", "source_org_type": "医院", "row_number": 64, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "aromatase inhibitor", "company": "Oslo University Hospital", "org_type": "医院", "target": "aromatase", "modality": "inhibitor", "importance_level": "低", "total_score": 29, "institution_score": 25, "track_score": 40, "milestone_score": 20, "field_heat_score": 35, "bonus_score": 0, "brief_reason": "芳香化酶抑制剂为经典内分泌治疗药物，靶点aromatase已高度成熟。机构为医院且摘要被embargo，缺乏新机制或显著临床里程碑信息，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11440", "id": "71XM_5wBX1NQZOEH-LG6", "source_drug_name": "aromatase inhibitor", "title": "Single cell DNA sequencing reveals clonal selection, hormonal adaptation and treatment resistance in neoadjuvant clinical trial of Aromatase inhibition", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Oslo University Hospital", "source_org_type": "医院", "row_number": 476, "target_meta": "aromatase", "MOA_meta": "抑制剂"}, {"drug_name": "aristolochic acid", "company": "ChomiX Biotech., Ltd.", "org_type": "公司", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 29, "institution_score": 45, "track_score": 20, "milestone_score": 10, "field_heat_score": 30, "bonus_score": 0, "brief_reason": "马兜铃酸为已知肾毒性天然化合物，本研究利用PAfBPP化学生物学平台进行毒性靶点鉴定，但摘要被embargo未披露具体靶点或新机制。ChomiX为国内中小型创新药企，研究属毒理机制探索而非药物开发赛道，preclinical工具性工作里程碑价值有限，故整体重要性低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11318", "id": "G1XM_5wBX1NQZOEH-LO6", "source_drug_name": "aristolochic acid", "title": "A chemoproteomic photoaffinity platform(PAfBPP) enables target identification and mechanistic dissection of aristolochic acid-induced nephrotoxicity", "abstract_text": "Abstract is embargoed at this time.", "source_company": "ChomiX Biotech., Ltd.", "source_org_type": "公司", "row_number": 668, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "molecular iodine", "company": "Universidad Nacional Autonoma de Mexico", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 29, "institution_score": 25, "track_score": 40, "milestone_score": 20, "field_heat_score": 30, "bonus_score": 0, "brief_reason": "分子碘（I2）作为乳腺癌化疗辅助剂，可改善化疗耐药和副作用，但摘要被禁，未披露具体靶点或机制细节。机构为大学非商业实体、开发阶段为preclinical或早期研究、赛道非热门创新modality，故整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/12134", "id": "E57M_5wBZznHJdnt_W7O", "source_drug_name": "molecular iodine", "title": "Molecular iodine impairs chemotherapy resistance and adverse effects in breast cancer treatments", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Universidad Nacional Autonoma de Mexico", "source_org_type": "大学", "row_number": 1141, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "isorhapontigenin", "company": "NYU Grossman School of Medicine", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 28.5, "institution_score": 25, "track_score": 40, "milestone_score": 20, "field_heat_score": 30, "bonus_score": 0, "brief_reason": "isorhapontigenin为天然多酚类化合物，摘要未明确其靶点，与FSP1抑制剂联用抑制三阴性乳腺癌细胞进展，但摘要被embargo无法获知具体机制。机构为大学非商业研发，开发阶段为preclinical早期，无明确里程碑，赛道为天然产物联合铁死亡相关方向热度一般，故总体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11428", "id": "LFXM_5wBX1NQZOEH-LO6", "source_drug_name": "isorhapontigenin", "title": "Combination of isorhapontigenin and FSP1 inhibitor suppresses triple negative breast cancer cell progression", "abstract_text": "Abstract is embargoed at this time.", "source_company": "NYU Grossman School of Medicine", "source_org_type": "大学", "row_number": 682, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "pinostilbene", "company": "Long Island University", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 28.2, "institution_score": 25, "track_score": 35, "milestone_score": 20, "field_heat_score": 40, "bonus_score": 2, "brief_reason": "pinostilbene为resveratrol单甲基化类似物，靶点机制未明确披露，仅在体外前列腺癌细胞系显示抗癌活性。大学机构+早期preclinical阶段+天然产物类似物赛道，整体创新性和开发潜力较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4990", "id": "xFXM_5wBX1NQZOEH-LS6", "source_drug_name": "pinostilbene", "title": "Pinostilbene exhibits anticancer activity in advanced prostate cancer", "abstract_text": "Prostate cancer is the foremost incident cancer and the second major cause of cancer-associated mortality among men in the U.S. Although current therapies, involving androgen receptor (AR) pathway inhibitors have improved survival rates, advanced prostate cancer remains a lethal disease. Therefore, new therapeutic approaches should continue to be investigated. Previous studies from our group as well as others have widely demonstrated the anticancer activity of resveratrol and its analogs. However, pinostilbene, a monomethylated resveratrol analog, is less well studied and reports on its anticancer activity in prostate cancer is limited. In this study, we investigated the anticancer activity of pinostilbene in prostate cancer. We found that pinostilbene inhibited the viability, proliferation, and metastatic potential of all prostate cancer cell lines tested. Of note, pinostilbene exhibited significantly higher potency as an anticancer agent in more invasive compared to less invasive prostate cancer cell lines. Overall, our results demonstrate that pinostilbene shows tremendous potential as an anticancer agent for improved management of prostate cancer.", "source_company": "Long Island University", "source_org_type": "大学", "row_number": 976, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "hnRNPH1/H2 inhibitor", "company": "Nova Southeastern University", "org_type": "大学", "target": "hnRNPH1/H2", "modality": "inhibitor", "importance_level": "低", "total_score": 28, "institution_score": 20, "track_score": 40, "milestone_score": 30, "field_heat_score": 40, "bonus_score": 2, "brief_reason": "靶向剪接体蛋白hnRNPH1/H2的抑制剂，在BRAF抑制剂耐药黑色素瘤中显示抗肿瘤活性并增强免疫应答；但来自大学机构、处于preclinical阶段、无明确临床里程碑，赛道非主流热门，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11439", "id": "5VXM_5wBX1NQZOEH-LG6", "source_drug_name": "hnRNPH1/H2 inhibitor", "title": "Therapeutic Targeting of Spliceosomal Proteins hnRNPH1/H2 Demonstrates Potent Anti-Melanoma Activity In BRAF Inhibitor Resistant Melanoma, and Enhances Tumor Immune Response", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Nova Southeastern University", "source_org_type": "大学", "row_number": 469, "target_meta": "hnRNPH1,hnRNPH2", "MOA_meta": "抑制剂"}, {"drug_name": "hexanoate", "company": "University of Puerto Rico Comprehensive Cancer Center", "org_type": "医院", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 27.5, "institution_score": 25, "track_score": 30, "milestone_score": 25, "field_heat_score": 35, "bonus_score": 0, "brief_reason": "hexanoate为微生物组相关中链脂肪酸，机制未明确特定靶点，仅在TNBC细胞系中显示体外抑制活性。机构为大学附属癌症中心且仅为preclinical初步研究，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8891", "id": "OlXM_5wBX1NQZOEH-LG5", "source_drug_name": "hexanoate", "title": "Inhibition of oncogenic phenotypes by hexanoate in triple-negative breast cancer", "abstract_text": "Background: Triple-Negative Breast Cancer (TNBC) is an invasive molecular subtype of breast cancer defined by the lack of estrogen and progesterone receptors, and the absence of HER2 amplification. This molecular profile limits current treatment options contributing to poor patient outcomes. Recent evidence features the microbiome as a key factor in cancer biology, modulating tumor progression through metabolites and bacterial products. Among these products, medium-chain fatty acids (MCFAs), such as hexanoate, are produced by microbial fermentation within the microbiome. Previous studies from our laboratory demonstrated that hexanoate reduces the viability and proliferative capacity in oral cancer cells, which may suggest hexanoate as a promising candidate target for alternative cancer treatments. Therefore, the aim of this study was to evaluate the impact of hexanoate on oncogenic phenotypes including cell viability, proliferation, and migration of the TNBC cell line MDA-MB-231.\nMethods: MDA-MB-231 cells were cultured at 37°C, 5% CO2 in RPMI-media. Cell viability was measured using AlamarBlue after 24, 48 and 72 hours (h) of treatment with sodium hexanoate at 9 different concentrations starting at 800mM (1:2 serial dilution) to measure the half-minimal inhibitory concentration (IC50). Cell proliferation was measured by seeding 100,000 cells per well and counting with TrypanBlue the change in cell number after treatment with hexanoate at 5mM for 24h, 48h and 72h. Cell migration was evaluated using a scratch assay; after inflicting a wound, its width was measured at 0h, 24h, and 48h to calculate the percentage of wound closure.\nResults: Hexanoate reduced cell viability at 24h, 48h, and 72h with a consistent IC50 of 29mM. Additionally, no significant effects on the proliferation rate were observed at 24h and 48h when treated with hexanoate, whereas it decreased significantly at 72h (p=0.004). Furthermore, hexanoate showed a decreased percentage of wound closure at both time points, showing significance at 48h (p = 0.002).\nConclusions: Overall, hexanoate exhibited inhibitory effects on viability, proliferation, and migration in TNBC cells. As a microbiome-associated compound, hexanoate may modulate cancer cell behavior in a time-dependent manner and represent a potential alternative target for TNBC treatment, although additional studies are required for validation.", "source_company": "University of Puerto Rico Comprehensive Cancer Center", "source_org_type": "医院", "row_number": 347, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "synthetic non-natural antibody against GRP", "company": "Centro de Investigación Biomédica de La Rioja (CIBIR)", "org_type": "研究机构", "target": "GRP", "modality": "other", "importance_level": "低", "total_score": 27.5, "institution_score": 25, "track_score": 35, "milestone_score": 20, "field_heat_score": 30, "bonus_score": 0, "brief_reason": "药物为针对GRP的合成非天然抗体（NoNabody），早期计算机模拟分析结合位点，尚无实验验证或体内数据。机构为区域性研究机构、非热门modality且仅in silico阶段导致整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/5485", "id": "5FXM_5wBX1NQZOEH-LG6", "source_drug_name": "synthetic non-natural antibody against GRP", "title": "Design of a synthetic non-natural antibody (NoNabody) against GRP as a new therapy for small cell lung cancer", "abstract_text": "(a) An introductory sentence indicating the purposes of the study; Gastrin-releasing peptide (GRP) has been described as an autocrine growth factor for small cell lung carcinoma (SCLC) and the use of a monoclonal antibody (MoAb) against GRP was shown to reduce tumor growth in animal models and had a positive profile in a phase 2 clinical trial. Here we aim to develop a synthetic non-natural antibody (NoNabody) as a potential new therapeutic tool for SCLC.\n(b) A brief description of pertinent experimental procedures; The first step to obtain a NoNabody against GRP was to study the interaction between a well-characterized anti-GRP MoAb and the peptide itself. After obtaining the sequence of the variable binding region, ColabFold was used to predict the antibody structure and VMD, together with NAMD, were used to analyze the antibody-peptide interaction.\n(c) A summary of the new, unpublished data; An in silico evaluation of the interaction between the anti-GRP antibody and the peptide identified the last seven residues of GRP, including the terminal amide group, as the main target of the antibody.Throughout all the molecular dynamics simulations, the MoAb remained structurally stable, whereas the full-length GRP peptide exhibited limited stability. In contrast, simulations performed with only the last 10 or 7 amino acids of the peptide showed increased stability.A comparison of the interactions between the amidated versus the free-acid peptide with the MoAb showed that amidation greatly enhances the antibody’s affinity for GRP.Analysis of the antibody-peptide interface revealed that the interaction is distributed between the heavy and light chains, with GRP positioned right in between them. CDR3 (light chain) interacts with the last three residues of GRP, whereas CDR1 and CDR2 (heavy chain) interact with residues 16-22.\n(d) A statement of the conclusions; NoNanobodies represent a new tool for employing antibodies in in vitro and in vivo studies. This work focuses on generating a NoNanobody against GRP. An initial in silico analysis showed that antibody-peptide binding occurs at the C-terminal amino acids and that this interaction is strengthened when GRP is amidated. This information is critical for developing new synthetic binding moieties against GRP that may improve drug performance through their small size, improved tissue penetrability and low immune responses to the small synthetic forms.\nThis work was supported by the Science and Innovation System of the Government of La Rioja (25658-2025/0000000016).", "source_company": "Centro de Investigación Biomédica de La Rioja (CIBIR)", "source_org_type": "研究机构", "row_number": 468, "target_meta": "GRP,LSM4", "MOA_meta": "其他"}, {"drug_name": "THBP-6", "company": "Manglayatan University", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 27.5, "institution_score": 25, "track_score": 30, "milestone_score": 25, "field_heat_score": 35, "bonus_score": 0, "brief_reason": "THBP-6为新型苯并吡喃磺酰胺衍生物，靶点机制未在摘要中披露，仅在MCF-7细胞系显示初步体外细胞毒活性（IC₅₀ 20.99 µg/mL）。机构为普通大学、处于极早期合成筛选阶段、无热门靶点或modality、整体开发价值较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8790", "id": "PVXM_5wBX1NQZOEH-LO6", "source_drug_name": "THBP-6", "title": "Synthesis and anti-cancer screening of benzopyran derivatives", "abstract_text": "Introduction: Global cancer incidence continues to rise, with an estimated 20 million new cases and 10 million deaths reported in 2025. Despite significant advances in early detection and therapeutic strategies, cancer remains one of the leading causes of mortality worldwide. Current research efforts are directed toward the discovery and development of novel compounds that offer enhanced anticancer efficacy with minimal side effects.\nObjectives of the Study: This study aims to synthesize and characterize a series of novel 2-(toluene sulfonamido)-3-cyano-7,7-dimethyl-4-substituted phenyl-5,6,7,8-tetrahydrobenzopyran-5-one derivatives and evaluate their anticancer potential against MCF-7 breast cancer cells. Cytotoxic activity is assessed using the MTT assay to determine IC₅₀ values, with the objective of identifying a potent lead compound for the development of an effective breast cancer therapy.\nExperimental Procedure: Substituted benzaldehyde and malononitrile were condensed in ethanol using sodium hydroxide to afford the arylidene-malononitrile intermediate which was subsequently refluxed with dimedone to yield the cyclized benzopyran compound, which was then treated with aryl sulfonyl chloride in the presence of triethylamine to furnish the final benzopyran derivatives. The reaction sequence proceeds through a Knoevenagel condensation followed by a Michael addition mechanism.\nSpectroscopic Characterization: The synthesized compounds (THBP2 to THBP8) were characterized by melting point, UV, IR, ¹H NMR, and mass spectrometry. The spectral data obtained were in good agreement with the proposed molecular structures, confirming the successful synthesis and purity of the target compounds. MTT assay in MCF-7 cell line The cytotoxic activity of THBP2 to THBP8 was evaluated against MCF-7 breast cancer cells using the MTT assay at concentrations ranging from 6.25-100 µg/ml. Cell viability was determined from the reduction of MTT to formazan, and IC₅₀ values were calculated from the dose response curves.\nResearch Outcome: A series of benzopyran derivatives were successfully synthesized and characterized using spectroscopic techniques. The MTT assay results demonstrated that THBP-6 exhibited the highest cytotoxic activity, with an IC₅₀ value of 20.99 µg/mL, highlighting its potential as a promising anticancer lead compound. THBP6 exhibits low IC₅₀ despite containing electron-donating groups, likely due to enhanced lipophilicity and optimal electronic or steric factors that promote stronger binding to the target in MCF-7 cells.\nConclusion: Five novel benzopyran derivatives were synthesized and screened for anticancer activity against MCF-7 cells. In future perspectives, the potent activity of THBP-6 suggests that sulphonamide and cyano substituted benzopyran scaffolds could be further optimized and explored as promising candidates for anticancer drug development.", "source_company": "Manglayatan University", "source_org_type": "大学", "row_number": 696, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "oleuropein", "company": "Fairfield University", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 27.5, "institution_score": 25, "track_score": 30, "milestone_score": 25, "field_heat_score": 35, "bonus_score": 0, "brief_reason": "橄榄苦苷为天然酚类化合物，在三阴性乳腺癌细胞系MDA-MB-231中显示剂量依赖的细胞毒性和凋亡诱导，同时诱导Prdx抗氧化蛋白表达，但无明确药物靶点。大学基础研究阶段，无显著开发里程碑，整体医药开发价值和赛道热度较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/2874", "id": "S1XM_5wBX1NQZOEH-LO6", "source_drug_name": "oleuropein", "title": "Oleuropein, a phenolic compound from olive leaves, exerts cytotoxicity and peroxiredoxin induction in MDA-MB-231 breast cancer cells", "abstract_text": "Extra virgin olive oil, a foundational element of the Mediterranean cuisine, has been widely associated with numerous health benefits, including the prevention of degenerative diseases and the promotion of longevity. A major bioactive component of the olive tree is oleuropein, a phenolic compound predominantly found in olive leaves and fruit. Oleuropein has been well-characterized for its potent antioxidant and anti-inflammatory properties, as well as its potential anticancer effects demonstrated in both animal and cell-based models. In this study, we investigated the effects of oleuropein on the human triple-negative breast cancer cell line MDA-MB-231. Cells were treated with oleuropein at concentrations of 50, 200, and 400 µg/mL, or 70% ethanol control. We assessed cell viability using the MTS assay, and cytotoxicity and apoptosis using a Caspase 3/7 activity. We found the highest concentration of oleuropein to induce a 3-fold decrease in viable cell density and an 8-fold increase in apoptosis. We also examined the effect of oleuropein on the expression of the peroxiredoxin (Prdx) gene family, which encodes thiol-specific antioxidant proteins known to protect cells from oxidative damage and that we previously demonstrated to be induced by oleuropein in MCF-7 cells. We found significant induction of Prdx gene expression in MDA-MB-231 cells by oleuropein, with a marked induction of Prdx1 with the 400 ug/ml treatment. Current research is aimed at measuring Prdx protein expression in oleuropein-treated cells, as well as the effect of Prdx suppression on oleuropein susceptibility. Together, these findings suggest that oleuropein exerts dose-dependent anticancer effects in MDA-MB-231 cells that result in a robust peroxiredoxin antioxidant protein response. Further exploration of the mechanism of action of oleuropein in MDA-MB-231 cells will provide important insights into its pro-oxidant effects and potential therapeutic applications.", "source_company": "Fairfield University", "source_org_type": "大学", "row_number": 704, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "Leptospermum petersonii methanol crude extract", "company": "University of Johannesburg", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 26.5, "institution_score": 25, "track_score": 30, "milestone_score": 20, "field_heat_score": 35, "bonus_score": 0, "brief_reason": "该提取物为天然植物粗提物，未明确具体活性成分及靶点，仅在体外显示弱细胞毒性和促凋亡作用。大学早期探索性研究，缺乏明确机制和开发里程碑，整体创新性和临床转化潜力低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6073", "id": "pVXM_5wBX1NQZOEH-LG6", "source_drug_name": "Leptospermum petersonii methanol crude extract", "title": "Leptospermum petersonii methanol and ethyl acetate crude extracts as antimetastatic and apoptotic effects against pancreatic and prostate cancer cells", "abstract_text": "Cancer remains number one health care challenge worldwide with an estimation of 1 in 9 people developing cancer in their lifetime. As cancer becomes increasingly prevalent, research focuses on finding palliative care and natural treatments that could transform cancer therapeutics. The aim of the project was to investigate the anti-cancer and anti-metastatic effects of medicinal plant Leptospermum petersonii’s active compounds against pancreatic and prostate cancer cells. The following techniques were employed: TLC, Column and NMR chromatography, alamarblue assay, ATP assay, wound healing assay, Hoechst Staining, caspase assay, Agarose gel (DNA fragmentation analysis) and RT-PCR. Through cell viability assay and IC₅₀ of approximately 100 µg/mL for the methanolic crude extract was identified with greater cytotoxic effect on MIA PaCa-2 than PC3 cells. The EtOAc extract showed cytotoxicity indices IC₅₀ > 100 µg/mL signifying 60% of the cells were viable even at a dose of 100 µg/mL and thus led to the termination of additional testing because of its ineffective potency. Caspase 3/7 assay and DNA fragmentation had shown some positive result in support of apoptosis. Wound healing demonstrated untreated cells healed the gap in 24 hours, whereas treated cells took longer to do so. Gene expression showed upregulation of RB1 and checkpoint 1 which are necessary for DNA damage and apoptosis induction. In conclusion, the results suggest that there might be compounds within L. petersonii extracts that can be exploited for anticancer agent.", "source_company": "University of Johannesburg", "source_org_type": "大学", "row_number": 426, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "iron supplementation", "company": "Koch Institute for Integrative Cancer Research at MIT", "org_type": "研究机构", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 26.5, "institution_score": 25, "track_score": 15, "milestone_score": 35, "field_heat_score": 40, "bonus_score": 0, "brief_reason": "铁补充用于改善胰腺癌慢性疾病贫血，机制为对抗hepcidin介导的铁隔离，非新靶点药物开发。机构为学术研究型、赛道非热门创新药物方向、仅动物模型初步概念验证导致总体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10682", "id": "sp3ECZ0B4z9FlvORyiZD", "source_drug_name": "iron supplementation", "title": "Iron supplementation rescues anemia of chronic disease in pancreatic ductal adenocarcinoma", "abstract_text": "Pancreatic cancer is a devastating malignancy that is rising in incidence and has nearly universal poor outcomes. We find rates of iron deficiency are high in pancreatic cancer patients and track with the high prevalence of anemia in these patients. From an evolutionary perspective, anemia of chronic disease is a condition seen where our bodies respond to an inflammatory insult, such as an infection, by sequestering iron from circulation to store the iron in peripheral tissues, such as muscle, to make this iron unavailable for pathogens. Our recent preliminary data suggest pancreatic cancer may act as the inflammatory stimulus to cause iron dysregulation and anemia. Analysis of a large cohort of pancreatic cancer patients shows both iron and hemoglobin decrease early in pancreatic cancer patients, suggesting of dysregulated iron metabolism. When pancreatic cancer is modeled in mice, decreases in hemoglobin and iron are also observed, as are increases in circulating hepcidin. Interestingly, supplementing mice with pancreatic cancer with iron improves anemia. Mechanistically, we want to understand why mice with PDAC develop anemia and analyzed Ter119-expressing erythrocyte differentiation and maturation in the bone marrow. We found that there is no defect in erythroid maturation in PDAC mice therefore its unlikely that defective erythropoiesis is the cause for anemia in PDAC. We also profiled Ter119-expression on the surface of F4/80-positive macrophages as a measure of hemophagocytosis and found that there is decreased Ter119-positive macrophages in PDAC so hemophagocytosis in the bone marrow is not the caused of anemia in PDAC. We find that iron-sequestering proteins such as hepcidin are increased throughout PDAC progression and iron sequestration in tumors and we find iron sequestration by many different cell types and tissues during PDAC. Hepcidin is known to cause iron sequestration in macrophages, which are the largest source of iron recycling and supply for heme and hemoglobin synthesis in the body. Furthermore, we observed decreased macrophage numbers in the bone marrows of PDAC mice. Hence, we proposed that PDAC leads to reduced iron-recycling by macrophages and this causes anemia of chronic disease. Therefore, iron supplementation is sufficient to rescue anemia in PDAC.", "source_company": "Koch Institute for Integrative Cancer Research at MIT", "source_org_type": "研究机构", "row_number": 1155, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "proteasome inhibitor", "company": "Case Western Reserve University", "org_type": "大学", "target": "未披露", "modality": "inhibitor", "importance_level": "低", "total_score": 26, "institution_score": 20, "track_score": 60, "milestone_score": 10, "field_heat_score": 40, "bonus_score": 0, "brief_reason": "药品为泛泛的蛋白酶体抑制剂，未披露具体靶点或化合物，仅为学术机制研究；机构为大学非商业实体，开发阶段仅preclinical概念，无明确里程碑，赛道虽有一定热度但整体学术性强无转化潜力。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11461", "id": "tVXM_5wBX1NQZOEH-LG6", "source_drug_name": "proteasome inhibitor", "title": "Pharmacologic TSC2 inhibition sensitizes acute myeloid leukemia to proteasome inhibition via mTORC1 mediated mitochondrial catastrophe", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Case Western Reserve University", "source_org_type": "大学", "row_number": 440, "target_meta": "not available", "MOA_meta": "抑制剂"}, {"drug_name": "Malformin A1", "company": "SQU", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 26, "institution_score": 20, "track_score": 30, "milestone_score": 30, "field_heat_score": 40, "bonus_score": 0, "brief_reason": "Malformin A1为海洋来源环五肽，通过调控ERK1/2和NF-κβ等癌基因信号通路逆转卵巢癌顺铂耐药，但靶点未明确披露。机构为大学非商业研发、仅细胞水平研究无明确临床里程碑，赛道为天然产物小分子非热门modality，故整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4913", "id": "B1XM_5wBX1NQZOEH-LO6", "source_drug_name": "Malformin A1", "title": "MalforminA1 reverts cisplatin resistance by modulating oncogenic signaling pathways in ovarian cancer", "abstract_text": "Ovarian cancer is a highly lethal gynecological malignancy, largely due to its late-stage diagnosis, frequent recurrence, and the development of chemoresistance. Standard treatment typically involves surgical debulking followed by chemotherapy, most commonly with platinum-based agents such as cisplatin. Unfortunately, many patients eventually develop resistance to these therapies, reducing treatment effectiveness and contributing to poor overall survival. These clinical challenges underscore the urgent need for novel therapeutic strategies that can overcome or prevent chemoresistance. Marine-derived compounds have recently emerged as a valuable source of potential anticancer agents, with several demonstrating potent biological activity. In our previous work, we identified multiple marine-derived molecules with promising anti-cancer properties, including Malformin A1 (MA1). MA1, a cyclic pentapeptide isolated from the marine fungus Aspergillus niger, exhibits cytotoxic activity against both cisplatin-sensitive (A2780S) and cisplatin-resistant (A2780CP) ovarian cancer cell lines. Building on these findings, the present study sought to elucidate the molecular pathways through which MA1 may reverse cisplatin resistance in ovarian cancer. In this study, we assessed the molecular pathways through which MA1 modulates cisplatin resistance in A2780CP cells, using the cisplatin-sensitive A2780S cell line as a reference. The expression of key cancer-related proteins, including ERK1/2 and NF-κβ, was analyzed by Western blot to evaluate the modulatory effects of MA1 on these signaling pathways. MA1 treatment resulted in a significant reduction of total MEK1/2, ERK1/2, and NF-κβ protein levels in A2780S cells, whereas in A2780CP cells, only NF-κβ expression was increased. Furthermore, phosphorylated ERK1/2 and NF-κβ levels were elevated, particularly in A2780CP cells, indicating activation of ERK1/2 and NF-κβ pathways, which play central roles in regulating cell survival and apoptosis. The cytotoxic effects of MA1 were more pronounced in cisplatin-resistant A2780CP cells, supporting the compound’s potential role in reversing cisplatin resistance. Activation of these signaling pathways following MA1 treatment may resensitize resistant cells to apoptosis or other cytotoxic mechanisms, thereby contributing to the overcoming of chemoresistance.In conclusion, our findings demonstrate that MA1 can reverse cisplatin resistance through the modulation of key oncogenic signaling pathways, highlighting its promise as a therapeutic candidate to improve treatment outcomes in ovarian cancer.", "source_company": "SQU", "source_org_type": "大学", "row_number": 658, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "Carrier platin", "company": "Houston Methodist Research Institute", "org_type": "研究机构", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 26, "institution_score": 20, "track_score": 40, "milestone_score": 20, "field_heat_score": 30, "bonus_score": 0, "brief_reason": "Carrier platin为一种铂类药物载体形式（可能是纳米或大分子递送系统），与低剂量聚焦X射线辐照联用显示更好肿瘤控制，但靶点和具体机制未披露。机构为研究机构非头部药企、摘要被embargo无具体开发阶段细节、赛道为铂类优化递送+放疗组合非当前最热领域，故总体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11349", "id": "rVXM_5wBX1NQZOEH-LO6", "source_drug_name": "Carrier platin", "title": "Carrier platin coupled with low dose focal SmART+ X-ray irradiation yields better tumor control than either alone", "abstract_text": "Abstract is embargoed at this time.", "source_company": "Houston Methodist Research Institute", "source_org_type": "研究机构", "row_number": 768, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "cinnamaldehyde", "company": "Trinity Health System", "org_type": "医院", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 26, "institution_score": 20, "track_score": 30, "milestone_score": 30, "field_heat_score": 40, "bonus_score": 0, "brief_reason": "肉桂醛为肉桂活性成分，在摘要中未明确特异性药物靶点，主要通过S期阻滞与TTF协同诱导TNBC细胞凋亡和生长抑制。机构为医院系统、非制药公司，处于体外协同研究早期阶段，无明确临床里程碑，整体开发重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/3967", "id": "QJ7M_5wBZznHJdnt_W3O", "source_drug_name": "cinnamaldehyde", "title": "Synergistic effects of next-generation Tumor-Treating Fields technology and cinnamaldehyde/cinnamon oil on apoptosis, cell cycle arrest and growth suppression in triple-negative breast cancer cells", "abstract_text": "Background:  Triple-negative breast cancer (TNBC), one of the most aggressive subtypes of breast cancer, accounts for 10-20% of breast cancers. Tumor-Treating Fields (TTF), disrupt mitotic spindle formation and induce apoptosis in TNBC cells. Cinnamaldehyde (CA), the active component of cinnamon, inhibits TNBC proliferation and promotes apoptosis. This study evaluated whether CA or cinnamon oil (CO) acts in synergy with TTF to enhance growth suppression, apoptosis, and cell-cycle arrest in TNBC cells. \nMethods:  MDA-MB-231 TNBC cells were seeded at 75,000 cells/mL and treated with CA (150 µM), CO (1:300 dilution), or vehicle controls. Frequency-modulated TTF (FM-TTFields) were applied continuously for 72 hours at 150 kHz (±10 kHz modulation using an 8.3 mHz triangle wave), 1.2 VRMS/cm. Cell proliferation was assessed by CyQUANT assay and Celigo imaging; apoptosis and cell-cycle distribution were analyzed by Annexin V/PI flow cytometry. Synergy was quantified using Bliss independence and Highest Single Agent (HSA) models. \nResults: \nCell death synergy: Cell death from combined treatments TTF+CA (96.7%) and TTF+CO (96.3%) exceeded single agents CA (93.6%), CO (86.1%), and TTF (40.0%). Synergy analysis by HSA and Bliss models confirmed synergy, stronger for TTF+CO (HSA Δ = +10.3 ± 2.5 points (pts), p = 0.02; Bliss Δ = +4.7 ± 1.7 pts, p = 0.042) than TTF+CA (HSA Δ = +3.2 ± 1.4 pts, p = 0.06; Bliss Δ = +0.9 ± 1.0 pt, p = 0.27). Combining TTF with CA or CO yields synergistic benefits, with TTF+CO showing the greatest effect. \nApoptosis synergy (Annexin V/PI):  TTF+CO (49.9%) and TTF+CA (65.5%) greatly surpassed CA (20.6%), CO (13.9%), and TTF (1.4%). Combinations increased apoptosis ~36-fold (TTF+CO) and ~48-fold (TTF+CD). Synergy was highest for TTF+CA (HSA Δ = +44.3 pts; Bliss Δ = +43.2 pts) versus TTF+CO (HSA Δ = +35.1 pts; Bliss Δ = +33.9 pts). Combining TTF with CA or CO substantially enhances apoptosis, with TTF+CA most effective. \nCell-cycle modulation:  CA and CO enriched the S phase relative to DMSO (Δ%: CO +10 pts; CA +8 pts). TTF induced strong G2/M accumulation (+18 pts). Combining TTF with CO further increased G2/M (+12 pts) with minimal S-phase change (+1 pt), while CA+TTF produced only a small G2/M shift (+2 pts). These patterns suggest mechanistic complementarity: CA and CO primarily arrest cells in the S phase, whereas TTF induce mitotic arrest (M phase). \nConclusions:  Combining FM-TTFields with cinnamon oil or cinnamaldehyde enhances TNBC cell death and apoptosis through complementary mechanisms—S-phase arrest and mitotic disruption—resulting in significant synergy for FM-TTFields combined with cinnamon oil or cinnamaldehyde. These findings support a novel, combinatorial strategy for treating TNBC. Future studies should validate these results in vivo and explore clinical translation.", "source_company": "Trinity Health System", "source_org_type": "医院", "row_number": 993, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "Nimbolide", "company": "University of California Davis", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 24.5, "institution_score": 25, "track_score": 20, "milestone_score": 25, "field_heat_score": 30, "bonus_score": 0, "brief_reason": "Nimbolide为 Neem 植物来源的天然 limonoid 化合物，靶点机制未明确披露，仅在犬膀胱癌细胞系中显示体外抑制增殖、自噬诱导及部分 EMT 抑制作用。大学早期体外研究+天然小分子非热门赛道+无明确临床开发节点，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/4701", "id": "QFXM_5wBX1NQZOEH-LG5", "source_drug_name": "Nimbolide", "title": "Targeting canine bladder cancer with Nimbolide, a Neem (Azadirachta indica) limonoid", "abstract_text": "Background: The 5-year relative survival rate for Bladder Cancer (BlCa) patients with distant metastases is about 9%. Hence, novel and innovative therapies for metastatic BlCa are required. Dogs were found to develop muscle-invasive BlCa (MIBC) spontaneously and 10% progress to distant metastases at the time of diagnoses. Currently most dogs with MIBC are treated with non-steroidal anti-inflammatory drugs (NSAIDs); however, <25% respond to them. Our quest was to identify low-cost natural compounds of low toxicity that can be used in dogs. Nimbolide, a limonoid extracted from Neem leaves, was found to have anti-tumor effects in human BlCa cell lines. Hence, we tested whether this natural product will be effective in canine BlCa cell lines.\nMethods: We obtained two canine BlCa cell lines - K9TCC-PU-AXC (AXC), that formed tumors in nude mice and K9TCC-PU-Pu (PuPu), which did not, from Dr. Deborah Knapp, Purdue University. Cell viability was estimated by MTT assay and by live/dead cell staining on 3D-printed spheroids. Flow cytometry was used to estimate the rate of apoptosis. Autophagy was estimated by the expression of LC3B and p62 whereas EMT was estimated by the expression of vimentin, Snail-1, Snail-2, and cell migration was estimated by scratch assay using a Cytation 5 platform.\nResults: Nimbolide was more effective in suppressing proliferation in PuPu cells (IC50 = 0.656 µM) compared to AXC cells (IC50 = 1.2 µM). Flow cytometric analysis showed that AXC did not undergo apoptosis in response to nimbolide whereas PuPu did; however, nimbolide caused autophagy in both cells. On the other hand, nimbolide prevented epithelial mesenchymal transition (EMT) and migration in AXC, but not in PuPu cells. These effects of nimbolide were not seen in human dermal fibroblasts, underlining the specificity and selectivity of nimbolide.\nConclusions: Based on these results, we intend to develop nimbolide as a therapeutic tool in the treatment of canine BlCa in future studies.\nAcknowledgements: The content is solely the responsibility of the authors and does not necessarily represent the official views of the National Institutes of Health, the Department of Veterans Affairs or the United States Government. We are grateful for a generous award from the University of California Comprehensive Cancer Center (UCDCCC) Support Grant (P30CA093373) for this project.", "source_company": "University of California Davis", "source_org_type": "大学", "row_number": 353, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "aromatase inhibitors", "company": "University of Minnesota", "org_type": "大学", "target": "aromatase", "modality": "inhibitor", "importance_level": "低", "total_score": 24, "institution_score": 30, "track_score": 20, "milestone_score": 10, "field_heat_score": 40, "bonus_score": 0, "brief_reason": "aromatase inhibitors为乳腺癌标准内分泌治疗药物，靶向aromatase抑制雌激素合成；但摘要聚焦其心血管副作用而非药物研发新进展，大学机构、非热门新赛道、无里程碑式创新，整体重要性低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/10317", "id": "gFXM_5wBX1NQZOEH-LG5", "source_drug_name": "aromatase inhibitors", "title": "Is endothelial dysfunction induced by aromatase inhibitors reversible after treatment?", "abstract_text": "Introduction: Breast cancer accounts for about one-third of all new female cancer diagnoses and remains the second leading cause of cancer-related mortality among women. Aromatase inhibitors (AIs) are a standard therapy for postmenopausal women with hormone receptor-positive breast cancer, improving disease-free survival compared to tamoxifen. However, prolonged AI use is linked to increased cardiovascular (CV) risk, including hypertension, dyslipidemia, and endothelial dysfunction, likely due to estrogen depletion. We previously demonstrated early impairment in endothelial function during AI therapy. This study assessed whether AI-induced endothelial dysfunction is reversible after AI discontinuation.\nMethods: Patients were recruited before or within one month of AI initiation (Pre/Early AI), at multiple time points during AI therapy, and after AI discontinuation (Post-AI) from two prospective studies: Aromatase Inhibitors and Vascular Health (AIVH) and Vascular Assessment in Breast Cancer Survivors Taking Aromatase Inhibitors (VABC). Patients with hypertension, hyperlipidemia, diabetes, or tobacco use were excluded. Vascular assessments, including the EndoPAT ratio for endothelial function and large and small artery elasticity indices for arterial stiffness, were conducted using the non-invasive EndoPAT 2000 and the HDI/PulseWave CR-2000 CV Profiling System. Lower EndoPAT ratios predict increased risk for future CV events and adverse outcomes. Plasma levels of estradiol, lipid profiles, interleukin-6 (IL-6), and tumor necrosis factor-alpha (TNF-α) were also measured. To evaluate the longitudinal changes in endothelial function during AI therapy, a model was fit using generalized estimating equations to assess how the EndoPAT ratio changed over time on AI.\nResults: EndoPAT ratio, was significantly impaired during AI therapy compared to the Pre/Early AI (Pre/Early AI mean: 1.92; AI mean: 1.03; p< 0.0001). The EndoPAT ratio declined as early as 6 months on AI (model-based mean at 6 months: 1.19, p-value = 0.0097) and showed a progressive decline with increasing duration of AI use (e.g., model-based mean at 5 years on AI: 0.92; p = 0.0003). Importantly, after AI discontinuation, the EndoPAT ratio was only partially and not significantly restored (mean: 1.12) despite the full restoration of estradiol levels and the long post-treatment follow-up period (mean: 3.93 years; range: 1.53-5.34). No significant differences were observed in large and small artery elasticity, blood pressure, or lipid profiles between groups. Circulating IL-6 and TNF-α significantly decreased following AI discontinuation compared to during AI (p < 0.05).\nConclusion: AI therapy is associated with significant and progressive endothelial dysfunction, which does not fully recover after treatment cessation, highlighting the importance of CV monitoring in breast cancer patients receiving long-term AI therapy.", "source_company": "University of Minnesota", "source_org_type": "大学", "row_number": 395, "target_meta": "aromatase", "MOA_meta": "抑制剂"}, {"drug_name": "statins", "company": "RI-McGill University Health Centre", "org_type": "医院", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 24, "institution_score": 20, "track_score": 30, "milestone_score": 20, "field_heat_score": 40, "bonus_score": 0, "brief_reason": "statins为老药再利用，摘要被embargo未披露具体靶点或机制细节，仅为医院学术机构基于scRNAseq和organoid筛选的食管腺癌再利用研究。机构非药企导致institution_score低，赛道为老药重定位而非热门新靶点/新modality，开发阶段初步且无明确里程碑，总分偏低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/11414", "id": "SFXM_5wBX1NQZOEH-LO6", "source_drug_name": "statins", "title": "Repurposing statins for locally advanced esophageal adenocarcinoma: Integrating scRNAseq, organoid based high throughput drug screening, and patient level clinical data", "abstract_text": "Abstract is embargoed at this time.", "source_company": "RI-McGill University Health Centre", "source_org_type": "医院", "row_number": 703, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "methanolic extract of Carpobrotus edulis", "company": "University of Johannesburg", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 23.5, "institution_score": 20, "track_score": 25, "milestone_score": 25, "field_heat_score": 30, "bonus_score": 0, "brief_reason": "该提取物为天然植物粗提物，主要通过激活TNF介导的外源性凋亡通路诱导胰腺癌细胞凋亡，但靶点未明确披露。大学机构+纯preclinical植物提取物研究，赛道非热门且缺乏明确里程碑，整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6541", "id": "-1XM_5wBX1NQZOEH-LG6", "source_drug_name": "methanolic extract of Carpobrotus edulis", "title": "Targeting apoptotic machinery using methanolic extracts of Carpobrotus edulis to suppress pancreatic cancer growth", "abstract_text": "Pancreatic cancer remains a formidable global health challenge. Current cancer treatments, such as chemotherapy are expensive and limited. Consequently, investigating alternative anticancer treatments, such as medicinal plants, is crucial. This study aimed to investigate the potential anticancer properties of a crude methanolic extract and isolated compounds from Carpobrotus edulis by targeting apoptotic machinery in pancreatic cancer cells (MIA PaCa2). Multiple assays, including Alamar blue, ATP, Hoechst staining, Caspase 3/7 activity, DNA fragmentation, and RT-qPCR, were conducted to assess apoptosis induction. The crude methanol and isolated compounds did not affect the MRC-5 non-cancerous cell line. Mechanistic investigations confirmed that the crude extract activated the extrinsic TNF-mediated apoptosis pathway, evidenced by a significant increase in TNF expression and caspase 3/7 activity, leading to DNA and nuclear fragmentation, chromatin condensation, and the formation of apoptotic bodies. The loss of cell confluence, supported by non-significant(p>0,05) downregulation of STAT3, further suggested inhibited cell growth. While some changes were observed in the expression of p53, Bak1, and Fas for both the crude extract and isolated compounds, these were not statistically significant (p>0,05). Protein-ligand docking studies of the identified 7,9-Ditert-butyl-oxaspiro [4.5] deca-6,9-diene-2,8-dione and 1-octadecanol proved the compounds as having high affinity for the selected ligands: TNFR, FADD, p53, Bak1, and STAT3. Future research will focus on the further purification and investigation of the most potent isolated compound.", "source_company": "University of Johannesburg", "source_org_type": "大学", "row_number": 483, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "CaMC-LP", "company": "Guru Nanak Dev University", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 23.2, "institution_score": 20, "track_score": 15, "milestone_score": 35, "field_heat_score": 25, "bonus_score": 2, "brief_reason": "CaMC-LP为大学提取的Cassia fistula树皮氯仿馏分脂质体封装制剂，主要活性成分为胡椒碱，无明确药物靶点，属天然产物抗癌研究。机构为普通大学、赛道非热门modality且早期preclinical、在体外体内显示活性但整体开发价值有限。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6757", "id": "fVXM_5wBX1NQZOEH-LS6", "source_drug_name": "CaMC-LP", "title": "Liposomes encapsulated chloroform fraction of Cassia fistula L. bark enhances anticancer efficacy in ehrlich ascites carcinoma mice model", "abstract_text": "Cancer remains one of the eminent causes of mortality and a major health concern profoundly influencing life expectancy worldwide. Cassia fistula L. commonly known as ‘Golden shower’ finds its application in the Ayurveda and Chinese traditional medicines. The phytoconstituents from the bark powder were obtained using organic solvents in the increasing order of polarity viz. CaMH (hexane fraction), CaMC (chloroform fraction), CaME (ethyl acetate fraction) and CaMM (methanol fraction). These bark fractions were tested for their cytotoxic potential in HeLa (cervical cancer), MCF-7 (breast cancer), LN-18 (brain glioblastoma), MG-63 (osteosarcoma), A431 (skin cancer), MIA PaCa-2 (pancreatic cancer) and normal cell line L929 (human fibroblast cells) using MTT assay. Among all the tested fractions, CaMC fraction shows highest selective cytotoxicity against HeLa cells with GI50 value of 41.53 µg/mL. Silica gel column chromatography of CaMC fraction yielded Cf-1 fraction spectroscopically deciphered as Piperine. It showed significant cytotoxicity against HeLa, MG-63 and MCF-7 cell line with GI50 of 0.10 mM, 0.37mM, 0.56 mM respectively. CaMC and Cf-1 fractions treated HeLa cells showed significant manifestations of apoptosis in morphological and flow cytometric investigations. These induced cell cycle arrest at G0/G1 phase in concentration-dependent manner. Molecular mechanistic studies of CaMC and Cf-1 fraction depicted upregulation of apoptotic markers including p53, caspase 3 and 9, and downregulation of Bcl-2. Furthermore, the in-vivo studies evaluated in Ehrlich Ascites Carcinoma-bearing Swiss albino mice showed that liposomal encapsulated CaMC fraction (CaMC-LP) resulted in 82.23% tumor growth inhibition in contrast to CaMC fraction with 60.81% tumor inhibition, comparable to 86.39% inhibition by 5-Fluorouracil. The use of liposomal encapsulation enhanced the anticancer efficacy in vitro, and in vivo showing significant tumor inhibition in EAC- bearing mice without inducing toxicity. These findings suggest that C. fistula L. bark constituents have cancer chemopreventive and chemotherapeutic potential which can further be exploited for the benefit of mankind.", "source_company": "Guru Nanak Dev University", "source_org_type": "大学", "row_number": 920, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "Neem (Azadirachta indica) leaf crude protein extract", "company": "Chapman University", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 22, "institution_score": 25, "track_score": 20, "milestone_score": 15, "field_heat_score": 30, "bonus_score": 0, "brief_reason": "Neem叶粗蛋白提取物为天然植物来源混合物，未明确特定分子靶点，仅显示对乳腺癌细胞系的初步体外细胞毒性。大学机构+早期探索性蛋白质组研究，缺乏临床开发价值和明确机制创新。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/6618", "id": "KFXM_5wBX1NQZOEH-LG5", "source_drug_name": "Neem (Azadirachta indica) leaf crude protein extract", "title": "Proteomic profiling of Neem (Azadirachta indica) leaves", "abstract_text": "Modern scientific studies have contributed largely to creating well -validated research data for the holistically rooted use of the Neem (Azadirachta Indica) tree in disease management. Neem’s astonishing historical and modern relevance reveal more evidence as to why Neem is the target of our study.Valuable studies have shown that the whole parts of the Neem tree are are markable natural source of more than 130 bioactive compounds, which are highly responsible for many therapeutic applications. Historically, Neem has been used as a source of complementary and traditional medicine Ayurvedic and Unani medicine for over 4,500 years. The mystical tree Neem originated from southern Asian countries. This research focuses on the proteomic profiling of Neem leaves and tests their anticancer potential on breast cancer cells. Recent Cancer studies have ranked breast cancer among the most rapidly increasing cancer types in women. Despite consistent advancements in therapies, breast cancer remains a concerning health issue and a deadly disease among women. Many of the existing and emerging Cancer therapies come with numerous drawbacks, increasing the thirst to find better the rapeutics from plant sources with safer and efficacious outcomes. Neem has shown a remarkable potential against cancer due to its wide range of biologically active compounds, including proteins. Studies on the proteins present in Neem remain largely unexplored. The reviewed SwissProt database in UniprotKB shows only three proteins reported from the Neem tree.Therefore, this study has great potential to explore the global proteomic profiling of Neem leaves. Further analysis has also evaluated the cytotoxic potential of proteins from Neem leaves against MDA-MB 231 breast cancer cell lines. The defatted Neem leaves were extracted in n -hexane, followed by extraction in a 20 mM Tris/HCl buffer, pH 8, and then precipitated using 80% ammonium sulfate. The crude extract was dialyzed in water using a 3.5MWCO dialysis tubing and then lyophilized. The anticancer assay of Neem leaves Crude protein at different concentrations was evaluated against MDA-MB-231 cells by using MTS assay, where cells were incubated for 24hours, followed by the treatment with Crude protein for 48 hours, and absorbance was measured at 490 nm. Concentration ranges (6.4- 0.2 mg/mL) showed inhibitory effects on MDA - MB 231 cells. Further, the downstream proteomics was achieved by purification of Crude using gel filtration chromatography first on Hiload Superdex-200 column. The electrophoretic profile was developed by SDS-PAGE electrophoresis using a 10% Tris/Glycine gel, confirmed the presence of proteins with MW ranging from 10 to 37 kDa. The Proteomic profiles were established by peptide mass fingerprinting using Q-tof LC-MS/MS. The bioinformatic analysis using PEAKS Studio X and the UniProtKB TrEMBL Viridiplantae database revealed 17 proteins in 11 groups at an FDR ≤ 1% with a minimum of two unique peptide matches.", "source_company": "Chapman University", "source_org_type": "大学", "row_number": 337, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "propionate", "company": "University of Puerto Rico", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 21.5, "institution_score": 20, "track_score": 25, "milestone_score": 15, "field_heat_score": 30, "bonus_score": 0, "brief_reason": "propionate为微生物代谢产物短链脂肪酸，在TNBC细胞系中显示抑制侵袭作用，但靶点和具体机制未披露，仅为体外初步研究。机构为大学、非热门赛道且无明确药物开发里程碑，导致整体重要性较低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/8902", "id": "5lXM_5wBX1NQZOEH-LG6", "source_drug_name": "propionate", "title": "Short-chain fatty acids suppress invasion and clonogenic survival in triple-negative breast cancer cells", "abstract_text": "Background: Triple-negative breast cancer (TNBC) accounts for 15-20% of all breast cancers. Defined by the absence of estrogen receptors, progesterone receptors, and HER2 expression, this subtype is highly aggressive and has limited therapeutic options, resulting in a five-year survival rate of 78% compared to over 90% for other subtypes. Previous data from our laboratory demonstrated that short-chain fatty acids (SCFAs), microbiota derived metabolites, reduce TNBC cell viability, proliferation, and migration, with butyrate showing the strongest inhibitory effects. However, the impact of SCFAs on invasion and long-term survival remains unclear.\nObjective: This study aimed to investigate the effects of SCFAs on invasion and clonogenic potential in a TNBC cell line (MDA-MB-231) as indicators of metastatic behavior and sustained proliferative capacity.\nMethods: MDA-MB-231 cells were treated with SCFAs butyrate, acetate, and propionate at 5 mM and invasion was assessed using Boyden chambers coated with Matrigel. Cells were seeded in the upper chamber in serum-free medium, while the lower chamber contained complete medium as a chemoattractant. After 24 hours, cells that passed through the Matrigel layer were fixed, stained, and quantified using ImageJ. To evaluate long-term proliferative potential, clonogenic assays were performed with butyrate-treated cells, chosen for its strong inhibitory effects on TNBC growth and migration. MDA-MB-231 cells were seeded at a density of 1,000 cells per well of a six-well plate and treated with butyrate at 1 mM and 5 mM for 9-10 days. Colonies were fixed, stained, photographed, and quantified using ImageJ.\nResults: Butyrate and propionate treatment significantly suppressed invasion compared to control (p<0.0001 and p=0.0031, respectively), while acetate had no significant effect in invasion (p=0.4084). Clonogenic assays showed complete inhibition of colony formation in cells treated with 1 mM and 5 mM butyrate, while control cells formed a mean of 429 colonies per well. Morphologically, treated cells displayed loss of adherence and rounded shapes consistent with cytotoxicity.\nConclusion: Butyrate and propionate significantly inhibited invasion of MDA-MB-231 cells, while butyrate also completely suppressed clonogenic survival. These findings align with our previous transcriptomic data indicating SCFA modulation of pathways involved in oncogenic processes such as migration and cell adhesion. SCFAs demonstrate potent inhibitory effects on metastatic behavior and long-term proliferation, supporting further investigation into their therapeutic potential.", "source_company": "University of Puerto Rico", "source_org_type": "大学", "row_number": 470, "target_meta": "not available", "MOA_meta": "其他"}, {"drug_name": "urethane", "company": "Indiana University", "org_type": "大学", "target": "未披露", "modality": "other", "importance_level": "低", "total_score": 18.5, "institution_score": 20, "track_score": 10, "milestone_score": 15, "field_heat_score": 30, "bonus_score": 0, "brief_reason": "urethane为经典化学致癌剂而非治疗药物，本摘要研究其诱导肺癌模型中的性别差异机制，无任何药物开发信息。机构为大学且赛道非治疗开发，导致整体重要性极低。", "url": "https://www.abstractsonline.com/pp8/#!/21436/presentation/7078", "id": "3lXM_5wBX1NQZOEH-LO6", "source_drug_name": "urethane", "title": "The role of sex hormones and sex chromosomes in urethane-induced lung carcinogenesis", "abstract_text": "Lung cancer is the leading cause of cancer-related deaths worldwide and remains among the top ten causes of mortality in the United States. Non-small cell lung cancer (NSCLC) constitutes approximately 85% of all lung cancer cases, with lung adenocarcinoma (LUAD) being the most prevalent subtype. Intriguingly, sex differences in lung cancer incidence and mortality have been observed, particularly among non-smokers, where LUAD is more common in females. Understanding the sex-specific mechanisms underlying LUAD progression is critical for developing targeted therapeutic strategies. In this study, we used the “four core genotypes” (FCG) ArnoJ (C57BL/6J background) mice in which gonadal sex is decoupled from the sex chromosome complement. We applied urethane-induced lung cancer protocol (a well-established mimic of human LUAD), to investigate the roles of gonadal hormones and sex chromosomes in lung tumor progression. Mice of 6-8 weeks of age received urethane (1 g/kg body mass, weekly for 10 weeks) or the same volume of PBS (control) injections and were evaluated after a 20-week tumorigenesis period. We assessed cytological changes in bronchoalveolar lavage fluid (BALF), changes in mice body weights, histological/immunohistochemical (IHC) analysis in fixed lung tissue. All animals experienced increased BALF total counts and weight loss after urethane treatment (vs. control). When comparing animals of different genotypes, we found that the XXM (female chromosomes, male gonads) displayed the most prominent weight reduction between urethane and control groups. When combining mice with the same chromosomes treated with urethane vs. PBS, animals with XX composition displayed a greater difference in weight than those with XY chromosomes. In contrast, when comparing animals with the same gonads, mice with male gonads showed a stronger effect in weight reduction than those with female gonads. Overall, BALF from urethane-treated mice had higher total cell counts than PBS-treated mice. Differences across genotypes were also noted. Our preliminary analysis indicates that mice with female gonads experienced a more prominent increase in cell counts than mice with male gonads. No apparent differences were noted when comparing animals with XX or XY chromosomes. The IHC analysis with anti-Ras (Q61R) antibody (Abcam) revealed that sex hormones have a statistically significant (p=0.00178) effect on mutated RAS (Q61R) levels independent of genotype. The IHC analysis on cell proliferation rate (Ki-67, CST) did not reveal significant differences between groups. In conclusion, our preliminary analysis of this pilot experiment revealed a potential contribution of sex hormones and sex chromosomes to urethane-induced weight loss and BALF counts. Further analysis of histological and molecular markers in these mice will reveal additional information that could help us understand sex-specific mechanisms of carcinogenesis.", "source_company": "Indiana University", "source_org_type": "大学", "row_number": 60, "target_meta": "not available", "MOA_meta": "其他"}];
